window.bibleReaderData = window.bibleReaderData || {chapters:{}};
window.bibleReaderData.chapters = window.bibleReaderData.chapters || {};
(function(chapters){ for (const b in chapters){ window.bibleReaderData.chapters[b]=window.bibleReaderData.chapters[b]||{}; for (const c in chapters[b]){ window.bibleReaderData.chapters[b][c]=window.bibleReaderData.chapters[b][c]||{}; Object.assign(window.bibleReaderData.chapters[b][c], chapters[b][c]); } } })({"GEN":{"1":{"hr":[{"v":1,"t":"U početku stvori Bog nebo i zemlju."},{"v":2,"t":"Zemlja bijaše pusta i prazna; tama se prostirala nad bezdanom i Duh Božji lebdio je nad vodama."},{"v":3,"t":"I reče Bog: “Neka bude svjetlost!” I bi svjetlost."},{"v":4,"t":"I vidje Bog da je svjetlost dobra; i rastavi Bog svjetlost od tame."},{"v":5,"t":"Svjetlost prozva Bog dan, a tamu prozva noć. Tako bude večer, pa jutro - dan prvi."},{"v":6,"t":"I reče Bog: “Neka bude svod posred voda da dijeli vode od voda!” I bi tako."},{"v":7,"t":"Bog načini svod i vode pod svodom odijeli od voda nad svodom."},{"v":8,"t":"A svod prozva Bog nebo. Tako bude večer, pa jutro - dan drugi."},{"v":9,"t":"I reče Bog: “Vode pod nebom neka se skupe na jedno mjesto i neka se pokaže kopno!” I bi tako."},{"v":10,"t":"Kopno prozva Bog zemlja, a skupljene vode mora. I vidje Bog da je dobro."},{"v":11,"t":"I reče Bog: “Neka proklija zemlja zelenilom - travom sjemenitom, stablima plodonosnim, koja, svako prema svojoj vrsti, na zemlji donose plod što u sebi nosi svoje sjeme. I bi tako."},{"v":12,"t":"I nikne iz zemlje zelena trava što se sjemeni, svaka prema svojoj vrsti, i stabla koja rode plodovima što u sebi nose svoje sjeme, svako prema svojoj vrsti. I vidje Bog da je dobro."},{"v":13,"t":"Tako bude večer, pa jutro - dan treći."},{"v":14,"t":"I reče Bog: “Neka budu svjetlila na svodu nebeskom da luče dan od noći, da budu znaci blagdanima, danima i godinama,"},{"v":15,"t":"i neka svijetle na svodu nebeskom i rasvjetljuju zemlju!” I bi tako."},{"v":16,"t":"I načini Bog dva velika svjetlila - veće da vlada danom, manje da vlada noću - i zvijezde."},{"v":17,"t":"I Bog ih postavi na svod nebeski da rasvjetljuju zemlju,"},{"v":18,"t":"da vladaju danom i noću i da rastavljaju svjetlost od tame. I vidje Bog da je dobro."},{"v":19,"t":"Tako bude večer, pa jutro - dan četvrti."},{"v":20,"t":"I reče Bog: “Nek' povrvi vodom vreva živih stvorova, i ptice nek' polete nad zemljom, svodom nebeskim!” I bi tako."},{"v":21,"t":"Stvori Bog morske grdosije i svakovrsne žive stvorove što mile i vrve vodom i ptice krilate svake vrste. I vidje Bog da je dobro."},{"v":22,"t":"I blagoslovi ih govoreći: “Plodite se i množite i napunite vode morske! I ptice neka se namnože na zemlji!”"},{"v":23,"t":"Tako bude večer, pa jutro - dan peti."},{"v":24,"t":"I reče Bog: “Neka zemlja izvede živa bića, svako prema svojoj vrsti: stoku, gmizavce i zvjerad svake vrste!” I bi tako."},{"v":25,"t":"I stvori Bog svakovrsnu zvjerad, stoku i gmizavce svake vrste. I vidje Bog da je dobro."},{"v":26,"t":"I reče Bog: “Načinimo čovjeka na svoju sliku, sebi slična, da bude gospodar ribama morskim, pticama nebeskim i stoci - svoj zemlji - i svim gmizavcima što puze po zemlji!”"},{"v":27,"t":"Na svoju sliku stvori Bog čovjeka, na sliku Božju on ga stvori, muško i žensko stvori ih."},{"v":28,"t":"I blagoslovi ih Bog i reče im: “Plodite se, i množite, i napunite zemlju, i sebi je podložite! Vladajte ribama u moru i pticama u zraku i svim živim stvorovima što puze po zemlji!”"},{"v":29,"t":"I doda Bog: “Evo, dajem vam sve bilje što se sjemeni, po svoj zemlji, i sva stabla plodonosna što u sebi nose svoje sjeme: neka vam budu za hranu!"},{"v":30,"t":"A zvijerima na zemlji i pticama u zraku i gmizavcima što puze po zemlji u kojima je dah života - neka je za hranu sve zeleno bilje!” I bi tako."},{"v":31,"t":"I vidje Bog sve što je učinio, i bijaše veoma dobro. Tako bude večer, pa jutro - dan šesti."}]},"2":{"hr":[{"v":1,"t":"Tako bude dovršeno nebo i zemlja sa svom svojom vojskom."},{"v":2,"t":"I sedmoga dana Bog dovrši svoje djelo koje učini. I počinu u sedmi dan od svega djela koje učini."},{"v":3,"t":"I blagoslovi Bog sedmi dan i posveti, jer u taj dan počinu od svega djela svoga koje učini."},{"v":4,"t":"To je postanak neba i zemlje, tako su stvarani. Kad je Jahve, Bog, sazdao nebo i zemlju,"},{"v":5,"t":"još nije bilo nikakva poljskoga grmlja po zemlji, još ne bijaše niklo nikakvo poljsko bilje, jer Jahve, Bog, još ne pusti dažda na zemlju i nije bilo čovjeka da zemlju obrađuje."},{"v":6,"t":"Ipak, voda je izvirala iz zemlje i natapala svu površinu zemaljsku."},{"v":7,"t":"Jahve, Bog, napravi čovjeka od praha zemaljskog i u nosnice mu udahne dah života. Tako postane čovjek živa duša."},{"v":8,"t":"I Jahve, Bog, zasadi vrt na istoku, u Edenu, i u nj smjesti čovjeka koga je napravio."},{"v":9,"t":"Tada Jahve, Bog, učini te iz zemlje nikoše svakovrsna stabla - pogledu zamamljiva a dobra za hranu - i stablo života, nasred vrta, i stablo spoznaje dobra i zla."},{"v":10,"t":"Rijeka je izvirala iz Edena da bi natapala vrt; odatle se granala u četiri kraka."},{"v":11,"t":"Prvom je ime Pišon, a optječe svom zemljom havilskom, u kojoj ima zlata."},{"v":12,"t":"Zlato je te zemlje dobro, a ima ondje i bdelija i oniksa."},{"v":13,"t":"Drugoj je rijeci ime Gihon, a optječe svu zemlju Kuš."},{"v":14,"t":"Treća je rijeka Tigris, a teče na istok od Ašura; četvrta je Eufrat."},{"v":15,"t":"Jahve, Bog, uzme čovjeka i postavi ga u edenski vrt da ga obrađuje i čuva."},{"v":16,"t":"Jahve, Bog, zapovjedi čovjeku: “Sa svakoga stabla u vrtu slobodno jedi,"},{"v":17,"t":"ali sa stabla spoznaje dobra i zla da nisi jeo! U onaj dan u koji s njega okusiš, zacijelo ćeš umrijeti!”"},{"v":18,"t":"I reče Jahve, Bog: “Nije dobro da čovjek bude sam: načinit ću mu pomoć kao što je on.”"},{"v":19,"t":"Tada Jahve, Bog, načini od zemlje sve životinje u polju i sve ptice u zraku i predvede ih čovjeku da vidi kako će koju nazvati, pa kako koje stvorenje čovjek prozove, da mu tako bude ime."},{"v":20,"t":"Čovjek nadjene imena svoj stoci, svim pticama u zraku i životinjama u polju. No čovjeku se ne nađe pomoć kao što je on."},{"v":21,"t":"Tada Jahve, Bog, pusti tvrd san na čovjeka te on zaspa, pa mu izvadi jedno rebro, a mjesto zatvori mesom."},{"v":22,"t":"Od rebra što ga je uzeo čovjeku napravi Jahve, Bog, ženu pa je dovede čovjeku."},{"v":23,"t":"Nato čovjek reče: “Gle, evo kosti od mojih kostiju, mesa od mesa mojega! Ženom neka se zove, od čovjeka kad je uzeta!”"},{"v":24,"t":"Stoga će čovjek ostaviti oca i majku da prione uza svoju ženu i bit će njih dvoje jedno tijelo."},{"v":25,"t":"A bijahu oboje goli - čovjek i njegova žena - ali ne osjećahu stida."}]},"3":{"hr":[{"v":1,"t":"Zmija bijaše lukavija od sve zvjeradi što je stvori Jahve, Bog. Ona reče ženi: “Zar vam je Bog rekao da ne smijete jesti ni s jednog drveta u vrtu?”"},{"v":2,"t":"Žena odgovori zmiji: “Plodove sa stabala u vrtu smijemo jesti."},{"v":3,"t":"Samo za plod stabla što je nasred vrta rekao je Bog: 'Da ga niste jeli! I ne dirajte u nj, da ne umrete!'”"},{"v":4,"t":"Nato će zmija ženi: “Ne, nećete umrijeti!"},{"v":5,"t":"Nego, zna Bog: onog dana kad budete s njega jeli, otvorit će vam se oči, i vi ćete biti kao bogovi koji razlučuju dobro i zlo.”"},{"v":6,"t":"Vidje žena da je stablo dobro za jelo, za oči zamamljivo, a za mudrost poželjno: ubere ploda njegova i pojede. Dade i svom mužu, koji bijaše s njom, pa je i on jeo."},{"v":7,"t":"Tada se obadvoma otvore oči i upoznaju da su goli. Spletu smokova lišća i naprave sebi pregače."},{"v":8,"t":"Uto čuju korak Jahve, Boga, koji je šetao vrtom za dnevnog povjetarca. I sakriju se - čovjek i njegova žena - pred Jahvom, Bogom, među stabla u vrtu."},{"v":9,"t":"Jahve, Bog, zovne čovjeka: “Gdje si?” - reče mu."},{"v":10,"t":"On odgovori: “Čuo sam tvoj korak po vrtu; pobojah se jer sam go, pa se sakrih.”"},{"v":11,"t":"Nato mu reče: “Tko ti kaza da si go? Ti si, dakle, jeo sa stabla s kojega sam ti zabranio jesti?”"},{"v":12,"t":"Čovjek odgovori: “Žena koju si stavio uza me - ona mi je dala sa stabla pa sam jeo.”"},{"v":13,"t":"Jahve, Bog, reče ženi: “Što si to učinila?” “Zmija me prevarila pa sam jela”, odgovori žena."},{"v":14,"t":"Nato Jahve, Bog, reče zmiji: “Kad si to učinila, prokleta bila među svim životinjama i svom zvjeradi divljom! Po trbuhu svome puzat ćeš i zemlju jesti sveg života svog!"},{"v":15,"t":"Neprijateljstvo ja zamećem između tebe i žene, između roda tvojeg i roda njezina: on će ti glavu satirati, a ti ćeš mu vrebati petu.”"},{"v":16,"t":"A ženi reče: “Trudnoći tvojoj muke ću umnožit, u mukama djecu ćeš rađati. Žudnja će te mužu tjerati, a on će gospodariti nad tobom.”"},{"v":17,"t":"A čovjeku reče: “Jer si poslušao glas svoje žene te jeo sa stabla s kojega sam ti zabranio jesti rekavši: S njega da nisi jeo! - evo: Zemlja neka je zbog tebe prokleta: s trudom ćeš se od nje hraniti svega vijeka svog!"},{"v":18,"t":"Rađat će ti trnjem i korovom, a hranit ćeš se poljskim raslinjem."},{"v":19,"t":"U znoju lica svoga kruh svoj ćeš jesti dokle se u zemlju ne vratiš: tÓa iz zemlje uzet si bio - prah si, u prah ćeš se i vratiti.”"},{"v":20,"t":"Svojoj ženi čovjek nadjene ime Eva, jer je majka svima živima."},{"v":21,"t":"I načini Jahve, Bog, čovjeku i njegovoj ženi odjeću od krzna pa ih odjenu."},{"v":22,"t":"Zatim reče Bog: “Evo, čovjek postade kao jedan od nas - znajući dobro i zlo! Da ne bi sada pružio ruku, ubrao sa stabla života pa pojeo i živio navijeke!”"},{"v":23,"t":"Zato ga Jahve, Bog, istjera iz vrta edenskoga da obrađuje zemlju iz koje je i uzet."},{"v":24,"t":"Istjera, dakle, čovjeka i nastani ga istočno od vrta edenskog, pa postavi kerubine i plameni mač koji se svjetlucao - da straže nad stazom koja vodi k stablu života."}]},"4":{"hr":[{"v":1,"t":"Čovjek pozna svoju ženu Evu, a ona zače i rodi Kajina, pa reče: “Muško sam čedo stekla pomoću Jahve!”"},{"v":2,"t":"Poslije rodi Abela, brata Kajinova; Abel postane stočar, a Kajin zemljoradnik."},{"v":3,"t":"I jednoga dana Kajin prinese Jahvi žrtvu od zemaljskih plodova."},{"v":4,"t":"A prinese i Abel od prvine svoje stoke, sve po izbor pretilinu. Jahve milostivo pogleda na Abela i njegovu žrtvu,"},{"v":5,"t":"a na Kajina i žrtvu njegovu ni pogleda ne svrati. Stoga se Kajin veoma razljuti i lice mu se namrgodi."},{"v":6,"t":"I Jahve reče Kajinu: “Zašto si ljut? Zašto ti je lice namrgođeno?"},{"v":7,"t":"Jer ako pravo radiš, vedrinom odsijevaš. A ne radiš li pravo, grijeh ti je kao zvijer na pragu što na te vreba; još mu se možeš oduprijeti.”"},{"v":8,"t":"Kajin pak reče svome bratu Abelu: “Hajdemo van!” I našavši se na polju, Kajin skoči na brata Abela te ga ubi."},{"v":9,"t":"Potom Jahve zapita Kajina: “Gdje ti je brat Abel?” “Ne znam”, odgovori. “Zar sam ja čuvar brata svoga?”"},{"v":10,"t":"Jahve nastavi: “Što si učinio? Slušaj! Krv brata tvoga iz zemlje k meni viče."},{"v":11,"t":"Stoga budi proklet na zemlji koja je rastvorila usta da proguta s ruke tvoje krv brata tvoga!"},{"v":12,"t":"Obrađivat ćeš zemlju, ali ti više neće davati svoga roda. Vječni ćeš skitalica na zemlji biti!”"},{"v":13,"t":"A Kajin reče Jahvi: “Kazna je moja odviše teška da se snosi."},{"v":14,"t":"Evo me tjeraš danas s plodnoga tla; moram se skrivati od tvoga lica i biti vječni lutalac na zemlji - tko me god nađe, može me ubiti.”"},{"v":15,"t":"A Jahve mu reče: “Ne! Nego tko ubije Kajina, sedmerostruka osveta na njemu će se izvršiti!” I Jahve stavi znak na Kajina, da ga tko, našavši ga, ne ubije."},{"v":16,"t":"Kajin ode ispred lica Jahvina u zemlju Nod, istočno od Edena, i ondje se nastani."},{"v":17,"t":"Kajin pozna svoju ženu te ona zače i rodi Henoka. Podigao je grad i grad prozvao imenom svoga sina - Henok."},{"v":18,"t":"Henoku se rodio Irad, a od Irada potekao Mehujael; od Mehujaela poteče Metušael, od Metušaela Lamek."},{"v":19,"t":"Lamek uzme dvije žene. Jedna se zvala Ada, a druga Sila."},{"v":20,"t":"Ada rodi Jabala, koji je postao praocem onih što pod šatorima žive sa stokom."},{"v":21,"t":"Bratu mu bijaše ime Jubal. On je praotac svih koji sviraju na liru i sviralu."},{"v":22,"t":"Sila rodi Tubal-Kajina, praoca onih koji kuju bakar i željezo. Tubal-Kajinovoj sestri bijaše ime Naama."},{"v":23,"t":"Lamek prozbori svojim ženama: “Ada i Sila, glas moj poslušajte! Žene Lamekove, čujte mi besjedu: Čovjeka sam ubio jer me ranio i dijete jer me udarilo."},{"v":24,"t":"Ako će Kajin biti osvećen sedmerostruko, Lamek će sedamdeset i sedam puta!”"},{"v":25,"t":"Adam pozna svoju ženu te ona rodi sina i nadjenu mu ime Šet. Reče ona: “Bog mi dade drugo dijete mjesto Abela, koga ubi Kajin.”"},{"v":26,"t":"Šetu se rodi sin, komu on nadjenu ime Enoš. Tada se počelo zazivati ime Jahvino."}]},"5":{"hr":[{"v":1,"t":"Ovo je povijest Adamova roda. Kad je Bog stvorio čovjeka, napravio ga je na priliku svoju;"},{"v":2,"t":"stvorio je muško i žensko. A kad ih je stvorio, blagoslovi ih i nazva - čovjek."},{"v":3,"t":"Kad je Adamu bilo sto i trideset godina, rodi mu se sin njemu sličan, na njegovu sliku; nadjenu mu ime Šet."},{"v":4,"t":"Po rođenju Šetovu Adam je živio osam stotina godina te mu se rodilo još sinova i kćeri."},{"v":5,"t":"Adam poživje u svemu devet stotina i trideset godina. Potom umrije."},{"v":6,"t":"Kad je Šetu bilo sto i pet godina, rodi mu se Enoš."},{"v":7,"t":"Po rođenju Enoševu Šet je živio osam stotina i sedam godina te mu se rodilo još sinova i kćeri."},{"v":8,"t":"Šet poživje u svemu devet stotina i dvanaest godina. Potom umrije."},{"v":9,"t":"Kad je Enošu bilo devedeset godina, rodi mu se Kenan."},{"v":10,"t":"Po rođenju Kenanovu Enoš je živio osam stotina i petnaest godina te mu se rodilo još sinova i kćeri."},{"v":11,"t":"Enoš poživje u svemu devet stotina i pet godina. Potom umrije."},{"v":12,"t":"Kad je Kenanu bilo sedamdeset godina, rodi mu se Mahalalel."},{"v":13,"t":"Po rođenju Mahalalelovu Kenan je živio osam stotina i četrdeset godina te mu se rodilo još sinova i kćeri."},{"v":14,"t":"Kenan poživje u svemu devet stotina i deset godina. Potom umrije."},{"v":15,"t":"Kad je Mahalalelu bilo šezdeset i pet godina, rodi mu se Jered."},{"v":16,"t":"Po rođenju Jeredovu Mahalalel je živio osam stotina i trideset godina te mu se rodilo još sinova i kćeri."},{"v":17,"t":"Mahalalel poživje u svemu osam stotina devedeset i pet godina. Potom umrije."},{"v":18,"t":"Kad je Jeredu bilo sto šezdeset i dvije godine, rodi mu se Henok."},{"v":19,"t":"Po rođenju Henokovu Jered je živio osam stotina godina te mu se rodilo još sinova i kćeri."},{"v":20,"t":"Jered poživje u svemu devet stotina šezdeset i dvije godine. Potom umrije."},{"v":21,"t":"Kad je Henoku bilo šezdeset i pet godina, rodi mu se Metušalah."},{"v":22,"t":"Henok je hodio s Bogom. Po rođenju Metušalahovu Henok je živio trista godina te mu se rodilo još sinova i kćeri."},{"v":23,"t":"Henok poživje u svemu trista šezdeset i pet godina."},{"v":24,"t":"Henok je hodio s Bogom, potom iščeznu; Bog ga uze."},{"v":25,"t":"Kad je Metušalahu bilo sto osamdeset i sedam godina, rodi mu se Lamek."},{"v":26,"t":"Po rođenju Lamekovu Metušalah je živio sedam stotina osamdeset i dvije godine te mu se rodilo još sinova i kćeri."},{"v":27,"t":"Metušalah poživje u svemu devet stotina šezdeset i devet godina. Potom umrije."},{"v":28,"t":"Kad su Lameku bile sto osamdeset i dvije godine, rodi mu se sin."},{"v":29,"t":"Nadjene mu ime Noa, govoreći: “Ovaj će nam pribavljati, u trudu i naporu naših ruku, utjehu iz zemlje koju je Bog prokleo.”"},{"v":30,"t":"Po rođenju Noinu Lamek je živio pet stotina devedeset i pet godina te mu se rodilo još sinova i kćeri."},{"v":31,"t":"Lamek poživje u svemu sedam stotina sedamdeset i sedam godina. Potom umrije."},{"v":32,"t":"Pošto je Noa proživio pet stotina godina, rode mu se Šem, Ham i Jafet."}]},"6":{"hr":[{"v":1,"t":"Kad su se ljudi počeli širiti po zemlji i kćeri im se narodile,"},{"v":2,"t":"opaze sinovi Božji da su kćeri ljudske pristale, pa ih uzimahu sebi za žene koje su god htjeli."},{"v":3,"t":"Onda Jahve reče: “Neće moj duh u čovjeku ostati dovijeka; čovjek je tjelesan, pa neka mu vijek bude stotinu dvadeset godina.”"},{"v":4,"t":"U ona su vremena - a i kasnije - na zemlji bili Nefili, kad su Božji sinovi općili s ljudskim kćerima pa im one rađale djecu. To su oni od starine po snazi glasoviti ljudi."},{"v":5,"t":"Vidje Jahve kako je čovjekova pokvarenost na zemlji velika i kako je svaka pomisao u njegovoj pameti uvijek samo zloća."},{"v":6,"t":"Jahve se pokaja i u svom srcu ražalosti što je načinio čovjeka na zemlji."},{"v":7,"t":"Reče Jahve: “Ljude koje sam stvorio izbrisat ću s lica zemlje - od čovjeka do zvijeri, puzavce i ptice u zraku - jer sam se pokajao što sam ih napravio.”"},{"v":8,"t":"Ali je Noa našao milost u očima Jahvinim."},{"v":9,"t":"Ovo je povijest Noina: Noa je bio čovjek pravedan i neporočan u svom vremenu. S Bogom je Noa hodio."},{"v":10,"t":"Tri su se sina rodila Noi: Šem, Ham i Jafet."},{"v":11,"t":"U očima Božjim zemlja se bila iskvarila; nepravdom se napunila."},{"v":12,"t":"I kad je Bog vidio kako se zemlja iskvarila - tÓa svako se biće na zemlji izopačilo -"},{"v":13,"t":"reče Bog Noi: “Odlučio sam da bude kraj svim bićima jer se zemlja napunila opačinom; i, evo, uništit ću ih zajedno sa zemljom."},{"v":14,"t":"Napravi sebi korablju od smolastoga drveta; korablju načini s prijekletima i obloži je iznutra i izvana paklinom."},{"v":15,"t":"A pravit ćeš je ovako: neka korablja bude trista lakata u duljinu, pedeset u širinu, a trideset lakata u visinu."},{"v":16,"t":"Na korablji načini otvor za svjetlo, završi ga jedan lakat od vrha. Vrata na korablji načini sa strane; neka ima donji, srednji i gornji kat."},{"v":17,"t":"Ja ću, evo, pustiti potop - vode na zemlju - da izgine svako biće pod nebom, sve u čemu ima dah života: sve na zemlji mora poginuti."},{"v":18,"t":"A s tobom ću učiniti Savez; ti ćeš ući u korablju - ti i s tobom tvoji sinovi, tvoja žena i žene tvojih sinova."},{"v":19,"t":"A od svega što je živo - od svih bića - uvedi u korablju od svakoga po dvoje da s tobom preživi, i neka budu muško i žensko."},{"v":20,"t":"Od ptica prema njihovim vrstama, od životinja prema njihovim vrstama i od svih stvorova što po tlu puze prema njihovim vrstama: po dvoje od svega neka uđe k tebi da preživi."},{"v":21,"t":"Sa sobom uzmi svega za jelo pa čuvaj da bude hrane tebi i njima.”"},{"v":22,"t":"Noa učini tako. Sve kako mu je Bog naredio, tako je izvršio."}]},"7":{"hr":[{"v":1,"t":"Onda Jahve reče Noi: “Uđi ti i sva tvoja obitelj u korablju, jer sam uvidio da si ti jedini preda mnom pravedan u ovom vremenu."},{"v":2,"t":"Uzmi sa sobom od svih čistih životinja po sedam parova: mužjaka i njegovu ženku."},{"v":3,"t":"Isto tako od ptica nebeskih po sedam parova - mužjaka i ženku - da im se sjeme sačuva na zemlji."},{"v":4,"t":"Jer ću do sedam dana pustiti dažd po zemlji četrdeset dana i četrdeset noći te ću istrijebiti s lica zemlje svako živo biće što sam ga načinio.”"},{"v":5,"t":"Noa učini sve kako mu je Jahve naredio."},{"v":6,"t":"Noi bijaše šest stotina godina kad je potop došao na zemlju."},{"v":7,"t":"I pred vodama potopnim uđu s Noom u korablju njegovi sinovi, njegova žena i žene sinova njegovih."},{"v":8,"t":"Od čistih životinja i od životinja koje nisu čiste, od ptica, od svega što zemljom puzi,"},{"v":9,"t":"uđe po dvoje - mužjak i ženka - u korablju s Noom, kako je Bog naredio Noi."},{"v":10,"t":"A sedmoga dana zapljušte potopne vode po zemlji."},{"v":11,"t":"U dan onaj - šestote godine Noina života, mjeseca drugog, dana u mjesecu sedamnaestog - navale svi izvori bezdana, rastvore se ustave nebeske."},{"v":12,"t":"I udari dažd na zemlju da pljušti četrdeset dana i četrdeset noći."},{"v":13,"t":"Onog dana uđe u korablju Noa i njegovi sinovi: Šem, Ham i Jafet, Noina žena i tri žene Noinih sinova s njima;"},{"v":14,"t":"oni, pa sve vrste životinja: stoka, gmizavci što po tlu gmižu, ptice i svakovrsna krilata stvorenja,"},{"v":15,"t":"uđu u korablju s Noom, po dvoje od svih bića što u sebi imaju dah života."},{"v":16,"t":"Što uđe, sve bijaše par, mužjak i ženka od svih bića, kako je Bog naredio Noi. Onda Jahve zatvori za njim vrata."},{"v":17,"t":"Pljusak je na zemlju padao četrdeset dana; vode sveudilj rasle i korablju nosile: digla se visoko iznad zemlje."},{"v":18,"t":"Vode su nad zemljom bujale i visoko rasle, a korablja plovila površinom."},{"v":19,"t":"Vode su sve silnije navaljivale i rasle nad zemljom, tako te prekriše sva najviša brda pod nebom."},{"v":20,"t":"Petnaest lakata dizale se vode povrh potonulih brda."},{"v":21,"t":"Izgiboše sva bića što se po zemlji kreću: ptice, stoka, zvijeri, svi gmizavci i svi ljudi."},{"v":22,"t":"Sve što u svojim nosnicama imaše dah života - sve što bijaše na kopnu - izgibe."},{"v":23,"t":"Istrijebi se svako biće s površja zemaljskog: čovjek, životinje, gmizavci i ptice nebeske, sve se izbrisa sa zemlje. Samo Noa ostade i oni što bijahu s njim u korablji."},{"v":24,"t":"Stotinu pedeset dana vladahu vode zemljom."}]},"8":{"hr":[{"v":1,"t":"Onda se Bog sjeti Noe, svih zvijeri i sve stoke što bijaše s njim u korablji, pa pokrenu vjetar nad zemljom da uzbije vodu."},{"v":2,"t":"Zatvoriše se izvori bezdanu i ustave nebeske, i dažd s neba prestade."},{"v":3,"t":"Polako se povlačile vode sa zemlje. Nakon stotinu pedeset dana vode su jenjale,"},{"v":4,"t":"a sedmoga mjeseca, sedamnaestog dana u mjesecu korablja se zaustavi na brdima Ararata."},{"v":5,"t":"Vode su neprestano opadale do desetog mjeseca, a prvoga dana desetog mjeseca pokažu se brdski vrhunci."},{"v":6,"t":"Kad je izminulo četrdeset dana, Noa otvori prozor što ga je načinio na korablji;"},{"v":7,"t":"ispusti gavrana, a gavran svejednako odlijetaše i dolijetaše dok se vode sa zemlje nisu isušile."},{"v":8,"t":"Zatim ispusti golubicu da vidi je li voda nestala sa zemlje."},{"v":9,"t":"Ali golubica ne nađe uporišta nogama te se vrati k njemu u korablju, jer voda još pokrivaše svu površinu; on pruži ruku, uhvati golubicu te je unese k sebi u korablju."},{"v":10,"t":"Počeka još sedam dana pa opet pusti golubicu iz korablje."},{"v":11,"t":"Prema večeri golubica se vrati k njemu, i gle! u kljunu joj svjež maslinov list; tako je Noa doznao da su opale vode sa zemlje."},{"v":12,"t":"Još počeka sedam dana pa opet pusti golubicu: više mu se nije vratila."},{"v":13,"t":"Šest stotina prve godine Noina života, prvoga mjeseca, prvog dana u mjesecu uzmakoše vode sa zemlje. Noa skine pokrov s korablje i pogleda: površina okopnjela."},{"v":14,"t":"A drugoga mjeseca, sedamnaestog dana u mjesecu, zemlja bijaše suha."},{"v":15,"t":"Tada Bog reče Noi:"},{"v":16,"t":"“Iziđi iz korablje, ti, tvoja žena, tvoji sinovi i žene tvojih sinova s tobom."},{"v":17,"t":"Sa sobom izvedi sva živa bića, sva stvorenja što su s tobom: ptice, stoku i sve gmizavce što zemljom puze; neka zemljom vrve, plode se i na zemlji množe!”"},{"v":18,"t":"I Noa iziđe, a s njime sinovi njegovi, žena njegova i žene sinova njegovih."},{"v":19,"t":"Sve životinje, svi gmizavci, sve ptice - svi stvorovi što se zemljom miču - iziđu iz korablje, vrsta za vrstom."},{"v":20,"t":"I podiže Noa žrtvenik Jahvi; uze od svih čistih životinja i od svih čistih ptica i prinese na žrtveniku žrtve paljenice."},{"v":21,"t":"Jahve omirisa miris ugodni pa reče u sebi: “Nikad više neću zemlju u propast strovaliti zbog čovjeka, tÓa čovječje su misli opake od njegova početka; niti ću ikad više uništiti sva živa stvorenja, kako sam učinio."},{"v":22,"t":"Sve dok zemlje bude, sjetve, žetve, studeni, vrućine, ljeta, zime, dani, noći nikada prestati neće.”"}]},"9":{"hr":[{"v":1,"t":"Tada Bog blagoslovi Nou i njegove sinove i reče im: “Plodite se i množite i zemlju napunite."},{"v":2,"t":"Neka vas se boje i od vas strahuju sve životinje na zemlji, sve ptice u zraku, sve što se po zemlji kreće i sve ribe u moru: u vaše su ruke predane."},{"v":3,"t":"Sve što se kreće i živi neka vam bude za hranu: sve vam dajem, kao što vam dadoh zeleno bilje."},{"v":4,"t":"Samo ne smijete jesti mesa u kojem je još duša, to jest njegova krv."},{"v":5,"t":"A za vašu krv, za vaš život, tražit ću obračun: tražit ću ga od svake životinje; i od čovjeka za njegova druga tražit ću obračun za ljudski život."},{"v":6,"t":"Tko prolije krv čovjekovu, njegovu će krv čovjek proliti! Jer na sliku Božju stvoren je čovjek!"},{"v":7,"t":"A vi, plodite se, i množite i zemlju napunite, i podložite je sebi!”"},{"v":8,"t":"Još reče Bog Noi i njegovim sinovima s njim:"},{"v":9,"t":"“A ja, evo, sklapam svoj Savez s vama i s vašim potomstvom poslije vas"},{"v":10,"t":"i sa svim živim stvorovima što su s vama: s pticama, sa stokom, sa zvijerima - sa svime što je s vama izišlo iz korablje - sa svim živim stvorovima na zemlji."},{"v":11,"t":"Držat ću se ja svog Saveza s vama te nikada više vode potopne neće uništiti živa bića niti će ikad više potop zemlju opustošiti.”"},{"v":12,"t":"I reče Bog: “A ovo znamen je Saveza koji stavljam između sebe i vas i svih živih bića što su s vama, za naraštaje buduće:"},{"v":13,"t":"Dugu svoju u oblak stavljam, da zalogom bude Savezu između mene i zemlje."},{"v":14,"t":"Kad oblake nad zemlju navučem i duga se u oblaku pokaže,"},{"v":15,"t":"spomenut ću se Saveza svoga, Saveza između mene i vas i stvorenja svakoga živog: potopa više neće biti da uništi svako biće."},{"v":16,"t":"U oblaku kad se pojavi duga, ja ću je vidjeti i vjekovnog ću se sjećati Saveza između Boga i svake žive duše, svakog tijela na zemlji.”"},{"v":17,"t":"I reče Bog Noi: “To neka je znak Saveza koji sam postavio između sebe i svih živih bića što su na zemlji.”"},{"v":18,"t":"Sinovi Noini, koji su iz korablje izišli, bijahu: Šem, Ham i Jafet. Ham je praotac Kanaanaca."},{"v":19,"t":"Ovo su trojica Noinih sinova i od njih se sav svijet razgranao."},{"v":20,"t":"Noa, zemljoradnik, zasadio vinograd."},{"v":21,"t":"Napio se vina i opio, pa se otkrio nasred šatora."},{"v":22,"t":"Ham, praotac Kanaanaca, opazi oca gola pa to kaza dvojici svoje braće vani."},{"v":23,"t":"Šem i Jafet uzmu ogrtač, obojica ga prebace sebi preko ramena pa njime, idući natraške, pokriju očevu golotinju. Lica im bijahu okrenuta na drugu stranu, tako te ne vidješe oca gola."},{"v":24,"t":"Kad se Noa otrijeznio od vina i saznao što mu je učinio najmlađi sin, reče:"},{"v":25,"t":"“Neka je proklet Kanaanac, braći svojoj najniži sluga nek' bude!”"},{"v":26,"t":"Onda nastavi: “Blagoslovljen Jahve, Šemov Bog, Kanaanac nek' mu je sluga!"},{"v":27,"t":"Nek Bog raširi Jafeta da prebiva pod šatorima Šemovim, Kanaanac nek' mu je sluga!”"},{"v":28,"t":"Poslije Potopa Noa poživje trista pedeset godina."},{"v":29,"t":"U svemu poživje Noa devet stotina pedeset godina; potom umrije."}]},"10":{"hr":[{"v":1,"t":"Ovo je povijest Noinih sinova: Šema, Hama i Jafeta, kojima su se rodili sinovi poslije Potopa."},{"v":2,"t":"Sinovi su Jafetovi: Gomer, Magog, Madaj, Javan, Tubal, Mešak, Tiras."},{"v":3,"t":"A sinovi su Gomerovi: Aškenaz, Rifat i Togarma."},{"v":4,"t":"Javanovi su opet sinovi: Eliša, Taršiš, Kitijci i Dodanci."},{"v":5,"t":"Od njih su se razgranali narodi po otocima. To su Jafetovi sinovi prema svojim zemljama - svaki s vlastitim jezikom - prema svojim plemenima i narodima."},{"v":6,"t":"Sinovi su Hamovi: Kuš i Misrajim, Put i Kanaan."},{"v":7,"t":"Kuševi su: Seba, Havila, Sabta, Rama i Sabteka. Ramini su: Šeba i Dedan."},{"v":8,"t":"Od Kuša se rodio Nimrod, koji je postao prvi velmoža na zemlji."},{"v":9,"t":"Voljom Jahve bio je silan lovac. Zato se veli: “Kao Nimrod, silan lovac voljom Jahve.”"},{"v":10,"t":"Glavno uporište njegova kraljevstva bili su: Babilon, Erek, Akad i Kalne, svi u zemlji Šinearu."},{"v":11,"t":"Iz ove je zemlje došao Ašur. On je podigao Ninivu, Rehobot Ir, Kalah"},{"v":12,"t":"i Resen između Ninive i Kalaha (to je glavni grad)."},{"v":13,"t":"Od Misrajima potekli su Ludijci, Anamijci, Lehabijci, Naftuhijci,"},{"v":14,"t":"pa Patrušani, Kasluhijci i Kaftorci, od kojih su potekli Filistejci."},{"v":15,"t":"Od Kanaana potječe Sidon, njegov prvenac, i Het."},{"v":16,"t":"Dalje: Jebusejci, Amorejci, Girgašani,"},{"v":17,"t":"Hivijci, Arkijci, Sinijci,"},{"v":18,"t":"Arvađani, Semarjani i Hamaćani. Poslije se kanaanska plemena razgranaše,"},{"v":19,"t":"tako da se granica Kanaanaca protezala od Sidona prema Geraru sve do Gaze pa prema Sodomi, Gomori, Admi i Sebojimu sve do Leše."},{"v":20,"t":"To su sinovi Hamovi prema svojim plemenima i jezicima, po svojim zemljama i narodima."},{"v":21,"t":"A i Šemu - praocu svih sinova Eberovih i starijem bratu Jafetovu - rodili se sinovi."},{"v":22,"t":"Šemovi su sinovi: Elam, Ašur, Arpakšad, Lud i Aram."},{"v":23,"t":"A Aramovi su sinovi: Us, Hul, Geter i Maš."},{"v":24,"t":"Arpakšad rodi Šelaha, Šelah rodi Ebera."},{"v":25,"t":"Eberu su se rodila dva sina: jednomu bješe ime Peleg, jer se za njegova vijeka zemlja razdijelila. Njegovu je bratu bilo ime Joktan."},{"v":26,"t":"Od Joktana se rodiše: Almodad, Šelef, Hasarmavet, Jerah,"},{"v":27,"t":"Hadoram, Uzal, Dikla,"},{"v":28,"t":"Obal, Abimael, Šeba,"},{"v":29,"t":"Ofir, Havila i Jobab. Sve su to sinovi Joktanovi."},{"v":30,"t":"Njihova se naselja protezahu od Meše sve do Sefara, brdovitih krajeva na istoku."},{"v":31,"t":"To su sinovi Šemovi prema svojim plemenima, jezicima i zemljama, po svojim narodima."},{"v":32,"t":"To su rodovi Noinih sinova prema svojim lozama i narodima. Od njih su se razgranali narodi po zemlji poslije Potopa."}]},"11":{"hr":[{"v":1,"t":"Sva je zemlja imala jedan jezik i riječi iste."},{"v":2,"t":"Ali kako su se ljudi selili s istoka, naiđu na jednu dolinu u zemlji Šinearu i tu se nastane."},{"v":3,"t":"Jedan drugome reče: “Hajdemo praviti opeke te ih peći da otvrdnu!” Opeke im bile mjesto kamena, a paklina im služila za žbuku."},{"v":4,"t":"Onda rekoše: “Hajde da sebi podignemo grad i toranj s vrhom do neba! Pribavimo sebi ime, da se ne raspršimo po svoj zemlji!”"},{"v":5,"t":"Jahve se spusti da vidi grad i toranj što su ga gradili sinovi čovječji."},{"v":6,"t":"Jahve reče. “Zbilja su jedan narod, s jednim jezikom za sve! Ovo je tek početak njihovih nastojanja. Sad im ništa neće biti neostvarivo što god naume izvesti."},{"v":7,"t":"Hajde da siđemo i jezik im pobrkamo, da jedan drugome govora ne razumije.”"},{"v":8,"t":"Tako ih Jahve rasu odande po svoj zemlji te ne sazidaše grada."},{"v":9,"t":"Stoga mu je ime Babel, jer je ondje Jahve pobrkao govor svima u onom kraju i odande ih je Jahve raspršio po svoj zemlji."},{"v":10,"t":"Ovo su potomci Šemovi: Kad je Šemu bilo sto godina - dvije godine poslije Potopa - rodi mu se Arpakšad."},{"v":11,"t":"Po rođenju Arpakšadovu Šem je živio petsto godina te mu se rodilo još sinova i kćeri."},{"v":12,"t":"Kad je Arpakšadu bilo trideset i pet godina, rodi mu se Šelah."},{"v":13,"t":"Po rođenju Šelahovu Arpakšad je živio četiri stotine i tri godine te mu se rodilo još sinova i kćeri."},{"v":14,"t":"Kad je Šelahu bilo trideset godina, rodi mu se Eber."},{"v":15,"t":"Po rođenju Eberovu Šelah je živio četiri stotine i tri godine te mu se rodilo još sinova i kćeri."},{"v":16,"t":"Kad su Eberu bile trideset i četiri godine, rodi mu se Peleg."},{"v":17,"t":"Po rođenju Pelegovu Eber je živio četiri stotine i trideset godina te mu se rodilo još sinova i kćeri."},{"v":18,"t":"Kad je Pelegu bilo trideset godina, rodi mu se Reu."},{"v":19,"t":"Po rođenju Reuovu Peleg je živio dvjesta i devet godina te mu se rodilo još sinova i kćeri."},{"v":20,"t":"Kad su Reuu bile trideset i dvije godine, rodi mu se Serug."},{"v":21,"t":"Po rođenju Serugovu Reu je živio dvjesta i sedam godina te mu se rodilo još sinova i kćeri."},{"v":22,"t":"Kad je Serugu bilo trideset godina, rodi mu se Nahor."},{"v":23,"t":"Po rođenju Nahorovu Serug je živio dvjesta godina te mu se rodilo još sinova i kćeri."},{"v":24,"t":"Kad je Nahoru bilo dvadeset i devet godina, rodi mu se Terah."},{"v":25,"t":"Po rođenju Terahovu Nahor je živio sto i devetnaest godina te mu se rodilo još sinova i kćeri."},{"v":26,"t":"Kad je Terahu bilo sedamdeset godina, rode mu se: Abram, Nahor i Haran."},{"v":27,"t":"Ovo je povijest Terahova. Terahu se rodio Abram, Nahor i Haran; a Haranu se rodio Lot."},{"v":28,"t":"Haran umrije za života svoga oca Teraha, u svome rodnom kraju, u Uru Kaldejskom."},{"v":29,"t":"Abram se i Nahor ožene. Abramovoj ženi bijaše ime Saraja, a Nahorovoj Milka; ova je bila kći Harana, oca Milke i Jiske."},{"v":30,"t":"Saraja bijaše nerotkinja - nije imala poroda."},{"v":31,"t":"Terah povede svoga sina Abrama, svog unuka Lota, sina Haranova, svoju snahu Saraju, ženu svoga sina Abrama, pa se zaputi s njima iz Ura Kaldejskoga u zemlju kanaansku. Kad stignu do Harana, ondje se nastane."},{"v":32,"t":"Dob Terahova dosegnu dvjesta i pet godina; a onda Terah umrije u Haranu."}]},"12":{"hr":[{"v":1,"t":"Jahve reče Abramu: “Idi iz zemlje svoje, iz zavičaja i doma očinskog, u krajeve koje ću ti pokazati."},{"v":2,"t":"Velik ću narod od tebe učiniti, blagoslovit ću te, ime ću ti uzveličati, i sam ćeš biti blagoslov."},{"v":3,"t":"Blagoslivljat ću one koji te blagoslivljali budu, koji te budu kleli, njih ću proklinjati; sva plemena na zemlji tobom će se blagoslivljati.”"},{"v":4,"t":"Abram se zaputi kako mu je Jahve rekao. S njime krenu i Lot. Abramu je bilo sedamdeset i pet godina kad je otišao iz Harana."},{"v":5,"t":"Abram uze sa sobom svoju ženu Saraju, svoga bratića Lota, svu imovinu što su je namakli i svu čeljad koju su stekli u Haranu te svi pođu u zemlju kanaansku. Kad su stigli u Kanaan,"},{"v":6,"t":"Abram prođe zemljom do mjesta Šekema - do hrasta More. Kanaanci su onda bili u zemlji."},{"v":7,"t":"Jahve se javi Abramu pa mu reče: “Tvome ću potomstvu dati ovu zemlju.” Abram tu podigne žrtvenik Jahvi koji mu se objavio."},{"v":8,"t":"Odatle prijeđe u brdoviti kraj, na istok od Betela. Svoj šator postavi između Betela na zapadu i Aja na istoku. Ondje podigne žrtvenik Jahvi i zazva ime Jahvino."},{"v":9,"t":"Od postaje do postaje Abram se pomicao prema Negebu."},{"v":10,"t":"Ali kad je zemljom zavladala glad, Abram se spusti u Egipat da ondje proboravi, jer je velika glad harala zemljom."},{"v":11,"t":"Kad je bio na ulazu u Egipat, reče svojoj ženi Saraji: “Znam da si lijepa žena."},{"v":12,"t":"Kad te Egipćani vide, reći će: 'To je njegova žena', i mene će ubiti, a tebe na životu ostaviti."},{"v":13,"t":"Nego reci da si mi sestra, tako da i meni bude zbog tebe dobro i da, iz obzira prema tebi, poštede moj život.”"},{"v":14,"t":"Zbilja, kad je Abram ušao u Egipat, Egipćani vide da je žena veoma lijepa."},{"v":15,"t":"Vide je faraonovi dvorani pa je pohvale faraonu i odvedu ženu na faraonov dvor."},{"v":16,"t":"Abramu pođe dobro zbog nje; steče on stoke i goveda, magaraca, slugu i sluškinja, magarica i deva."},{"v":17,"t":"Ali Jahve udari faraona i njegov dom velikim nevoljama zbog Abramove žene Saraje."},{"v":18,"t":"I faraon pozva Abrama pa reče: “Što si mi to učinio? Zašto mi nisi kazao da je ona tvoja žena?"},{"v":19,"t":"Zašto si rekao: 'Ona mi je sestra', pa je ja uzeh sebi za ženu? A sad, evo ti žene; uzmi je i hajde!”"},{"v":20,"t":"Faraon ga onda preda momcima, a oni ga otprave s njegovom ženom i sa svime što bijaše njegovo."}]},"13":{"hr":[{"v":1,"t":"Iz Egipta Abram ode gore u Negeb sa svojom ženom i sa svime što je imao. I Lot bješe s njim."},{"v":2,"t":"Abram je bio veoma bogat stokom, srebrom i zlatom."},{"v":3,"t":"Od postaje do postaje iz Negeba išao je do Betela,"},{"v":4,"t":"do mjesta na kojem je bio postavio šator, između Betela i Aja, gdje je prije podigao žrtvenik. Tu je Abram zazivao ime Jahvino."},{"v":5,"t":"I Lot, koji iđaše s Abramom, imaše ovaca, goveda i šatora,"},{"v":6,"t":"tako da ih kraj ne bi izdržavao kad bi zajedno ostali. Njihovo je blago bilo veliko, te zajedno nisu mogli boraviti."},{"v":7,"t":"Svađa je nastajala između pastira stoke Abramove i pastira stoke Lotove. Tada su zemlju nastavali Kanaanci i Perižani."},{"v":8,"t":"Zato Abram reče Lotu: “Neka ne bude svađe između mene i tebe, između pastira mojih i tvojih - tÓa mi smo braća!"},{"v":9,"t":"Nije li sva zemlja pred tobom? Odvoji se od mene! Kreneš li ti nalijevo, ja ću nadesno; ako ćeš ti nadesno, ja ću nalijevo.”"},{"v":10,"t":"Lot podiže oči i vidje kako je dobro posvuda natapana sva Jordanska dolina, kao kakav vrt Jahvin, kao zemlja egipatska prema Soaru. - Bilo je to prije nego što je Jahve uništio Sodomu i Gomoru. -"},{"v":11,"t":"Lot izabere za se svu Jordansku dolinu i ode na istok. Tako se odijele jedan od drugoga."},{"v":12,"t":"Abram ostade u kanaanskoj zemlji, dok je Lot živio po mjestima u dolini i razapeo svoje šatore do Sodome."},{"v":13,"t":"A žitelji Sodome bijahu veoma opaki, sami grešnici protiv Jahve."},{"v":14,"t":"Jahve reče Abramu, pošto se Lot od njega rastao: “Oči svoje podigni i s mjesta na kojem si pogledaj prema sjeveru, jugu, istoku i zapadu;"},{"v":15,"t":"jer svu zemlju što je možeš vidjeti dat ću tebi i tvome potomstvu zauvijek."},{"v":16,"t":"Potomstvo ću tvoje učiniti kao prah na zemlji. Ako tko mogne prebrojiti prah zemlje, i tvoje će potomstvo moći prebrojiti."},{"v":17,"t":"Na noge! Prođi zemljom uzduž i poprijeko jer ću je tebi predati.”"},{"v":18,"t":"Abram digne šatore i dođe pa se naseli kod hrasta Mamre, što je u Hebronu. Ondje podigne žrtvenik Jahvi."}]},"14":{"hr":[{"v":1,"t":"Kad Amrafel bijaše kralj Šineara, Ariok kralj Elasara, Kedor-Laomer kralj Elama, Tidal kralj Gojima,"},{"v":2,"t":"povedoše oni rat protiv Bere, kralja Sodome, Birše, kralja Gomore, Šinaba, kralja Adme, Šemebera, kralja Sebojima, i protiv kralja u Beli, to jest Soaru."},{"v":3,"t":"I vojske se sliju u dolinu Sidim, gdje je danas Slano more."},{"v":4,"t":"Dvanaest su godina služili Kedor-Laomera, ali trinaeste godine dignu se na ustanak."},{"v":5,"t":"U četrnaestoj godini digne se Kedor-Laomer i kraljevi koji su bili s njim te potuku Refaimce u Ašterot Karnajimu, Zuzijce u Hamu, Emijce na ravnici Kirjatajimu,"},{"v":6,"t":"Horijce u brdskom kraju Seiru, blizu El Parana, koji je uz pustinju."},{"v":7,"t":"Onda se povuku natrag i stignu u En Mišpat, to jest Kadeš, i pokore sve krajeve Amalečana i Amorejaca, koji su nastavali Haseson Tamar."},{"v":8,"t":"Zatim istupi kralj Sodome, kralj Gomore, kralj Adme, kralj Sebojima i kralj Bele, odnosno Soara, te zapodjenu borbu protiv onih u dolini Sidimu:"},{"v":9,"t":"Kedor-Laomera, kralja Elama, Tidala, kralja Gojima, Amrafela, kralja Šineara, Arioka, kralja Elasara - četiri kralja protiv pet."},{"v":10,"t":"Dolina Sidim bila je puna provalija s paklinom, pa kraljevi Sodome i Gomore, na bijegu, u njih poskaču, a ostali izmaknu u planine."},{"v":11,"t":"Pobjednici pokupe sve blago po Sodomi i Gomori i svu hranu pa odu."},{"v":12,"t":"Pograbe i Lota, Abramova bratića - i on je živio u Sodomi - i njegovo blago pa otiđu."},{"v":13,"t":"A bjegunac neki - rođak Eškola i Anera, Abramovih saveznika - donese vijest Abramu Hebrejcu dok je boravio kod hrasta Amorejske Mamre."},{"v":14,"t":"Kad je Abram čuo da mu je bratić zarobljen, skupi svoju momčad - rođenu u njegovu domu - njih trista osamnaest, pa pođe u potjeru do Dana."},{"v":15,"t":"Podijeli svoje momke u dvije čete, napadne noću te one potuče. Progonio ih je do Hobe, sjeverno od Damaska."},{"v":16,"t":"Povrati sve blago, svoga bratića Lota i njegovo blago, žene i ostali svijet."},{"v":17,"t":"Pošto se vratio, porazivši Kedor-Laomera i kraljeve koji su bili s njim, u susret mu, u dolinu Šave, to jest u Kraljev dol, iziđe kralj Sodome."},{"v":18,"t":"A Melkisedek, kralj Šalema, iznese kruha i vina. On je bio svećenik Boga Svevišnjega."},{"v":19,"t":"Blagoslovi ga govoreći: “Od Boga Svevišnjega, Stvoritelja neba i zemlje, neka je Abramu blagoslov!"},{"v":20,"t":"I Svevišnji Bog, što ti u ruke preda neprijatelje, hvaljen bio!” Abram mu dade desetinu od svega."},{"v":21,"t":"Tada kralj Sodome reče Abramu: “Meni daj ljude, a dobra uzmi sebi!”"},{"v":22,"t":"Abram odgovori kralju Sodome: “Ruku uzdižem pred Jahvom, Svevišnjim Stvoriteljem neba i zemlje,"},{"v":23,"t":"da neću uzeti ni končića, ni remena od obuće, niti išta što je tvoje da ne kažeš: na meni se Abram obogatio."},{"v":24,"t":"Ne, meni ništa, osim što su moji momci upotrijebili; i dio za momčad što je sa mnom išla: Aner, Eškol i Mamre, oni neka uzmu svoj dio.”"}]},"15":{"hr":[{"v":1,"t":"Poslije tih događaja Jahve uputi Abramu riječ u ukazanju: “Ne boj se, Abrame, ja sam ti zaštita; a nagrada tvoja bit će vrlo velika!”"},{"v":2,"t":"Abram odgovori: “Gospodine moj, Jahve, čemu mi tvoji darovi kad ostajem bez poroda; kad je mojoj kući nasljednik Eliezer Damaščanin?"},{"v":3,"t":"Kako mi nisi dao potomstva - nastavi Abram - jedan će, eto, od mojih ukućana postati moj baštinik.”"},{"v":4,"t":"Ali mu Jahve opet uputi riječ: “Taj neće biti tvoj baštinik, nego će ti baštinik biti tvoj potomak.”"},{"v":5,"t":"Izvede ga van i reče: “Pogledaj na nebo i zvijezde prebroj ako ih možeš prebrojiti.” A onda doda: “Toliko će biti tvoje potomstvo.”"},{"v":6,"t":"Abram povjerova Jahvi, i on mu to uračuna u pravednost."},{"v":7,"t":"Tada mu on reče: “Ja sam Jahve koji sam te odveo iz Ura Kaldejskoga da ti predam ovu zemlju u posjed.”"},{"v":8,"t":"A on odvrati: “Gospodine moj, Jahve, kako ću ja doznati da ću je zaposjesti?”"},{"v":9,"t":"Odgovori mu: “Prinesi mi junicu od tri godine, kozu od tri godine, ovna od tri godine, jednu grlicu i jednog golubića.”"},{"v":10,"t":"Sve mu to donese, rasiječe na pole i metnu sve pole jednu prema drugoj; ptica nije rasijecao."},{"v":11,"t":"Ptice grabežljivice obarale se na leševe, ali ih je Abram rastjerivao."},{"v":12,"t":"Kad je sunce bilo pri zalazu, dubok san obuzme Abrama, a onda se na nj spusti gust mrak pun jeze."},{"v":13,"t":"Tada Bog reče Abramu: “Dobro znaj da će tvoji potomci biti stranci u tuđoj zemlji; robovat će i biti tlačeni četiri stotine godina,"},{"v":14,"t":"ali narodu kojem budu služili ja ću suditi; i konačno će izići s velikim blagom."},{"v":15,"t":"A ti ćeš k ocima svojim u miru poći, u sretnoj starosti bit ćeš sahranjen."},{"v":16,"t":"Oni će se ovamo vratiti za četvrtog naraštaja, jer mjera se zlodjela amorejskih još nije navršila.”"},{"v":17,"t":"Kad je sunce zašlo i pao gust mrak, pojavi se zadimljen žeravnjak i goruća zublja te prođu između onih dijelova."},{"v":18,"t":"Toga je dana Jahve sklopio Savez s Abramom rekavši: “Potomstvu tvojemu dajem zemlju ovu od Rijeke u Egiptu do Velike rijeke, rijeke Eufrata:"},{"v":19,"t":"Kenijce, Kenižane, Kadmonce,"},{"v":20,"t":"Hetite, Perižane, Refaimce,"},{"v":21,"t":"Amorejce, Kanaance, Girgašane, Jebusejce.”"}]},"16":{"hr":[{"v":1,"t":"Abramova žena Saraja nije mu rađala djece. A imaše ona sluškinju Egipćanku - zvala se Hagara."},{"v":2,"t":"I reče Saraja Abramu: “Vidiš, Jahve me učinio nerotkinjom. Hajde k mojoj sluškinji, možda ću imati djece.” Abram posluša riječ Sarajinu."},{"v":3,"t":"Tako, pošto je Abram proboravio deset godina u zemlji kanaanskoj, njegova žena Saraja uzme Hagaru, Egipćanku, sluškinju svoju, pa je dade svome mužu Abramu za ženu."},{"v":4,"t":"Uđe on k Hagari te ona zače. A kad je vidjela da je začela, s prezirom je gledala na svoju gospodaricu."},{"v":5,"t":"Tada reče Saraja Abramu: “Nepravda što se meni nanosi tvoja je krivnja! Prepustila sam svoju sluškinju tvome zagrljaju, ali otkako opazi da je zanijela, s prezirom na me gleda. Jahve sudio i meni i tebi!”"},{"v":6,"t":"Nato Abram odvrati Saraji: “Tvoja je sluškinja u tvojoj ruci: kako ti se čini da je dobro, tako prema njoj postupi!” Saraja postupi prema njoj tako loše da ona od nje pobježe."},{"v":7,"t":"Anđeo Jahvin nađe je kod izvora u pustinji - uz vrelo što je na putu prema Šuru -"},{"v":8,"t":"pa je zapita: “Hagaro, sluškinjo Sarajina, odakle dolaziš i kamo ideš?” “Bježim, evo, od svoje gospodarice Saraje”, odgovori ona."},{"v":9,"t":"Nato joj anđeo Jahvin reče: “Vrati se svojoj gospodarici i pokori joj se!”"},{"v":10,"t":"Još joj reče anđeo Jahvin: “Tvoje ću potomstvo silno umnožiti; od mnoštva se neće moći ni prebrojiti.”"},{"v":11,"t":"Dalje joj je anđeo Jahvin rekao: “Gle, zanijela si i rodit ćeš sina. Nadjeni mu ime Jišmael, jer Jahve ču jad tvoj."},{"v":12,"t":"On će biti kao divlje magare: ruka će se njegova dizati na svakoga i svačija ruka na njega; i pred licem sve mu braće on će stan sebi podići.”"},{"v":13,"t":"A Jahvu koji joj govoraše nazva: “Ti si El Roi - Svevid Bog”, jer - reče ona - “vidjeh Boga i nakon viđenja - još živim!”"},{"v":14,"t":"Stoga se taj zdenac zove Beer Lahaj Roi - Zdenac životvornog Svevida, a eno ga između Kadeša i Bereda."},{"v":15,"t":"Rodi Hagara Abramu sina, a Abram sinu što mu ga rodi Hagara nadjene ime Jišmael."},{"v":16,"t":"Abramu je bilo osamdeset i šest godina kad mu je Hagara rodila Jišmaela."}]},"17":{"hr":[{"v":1,"t":"Kad je Abramu bilo devedeset i devet godina, ukaza mu se Jahve pa mu reče: “Ja sam El Šadaj - Bog Svesilni, Mojim hodi putem i neporočan budi."},{"v":2,"t":"A Savez svoj ja sklapam s tobom i silno ću te razmnožiti.”"},{"v":3,"t":"Abram pade ničice dok mu Bog govoraše dalje:"},{"v":4,"t":"“A ovo je Savez moj s tobom: postat ćeš ocem mnogim narodima;"},{"v":5,"t":"i nećeš se više zvati Abram - već Abraham će ti ime biti, jer naroda mnogih ocem ja te postavljam."},{"v":6,"t":"Silno ću te rodnim učiniti; narode ću iz tebe izvesti; i kraljevi će od tebe izaći."},{"v":7,"t":"Savez svoj sklapam između sebe i tebe i tvoga potomstva poslije tebe - Savez svoj za vjekove: ja ću biti Bogom tvojim i tvoga potomstva poslije tebe."},{"v":8,"t":"Tebi i tvome potomstvu poslije tebe dajem zemlju u kojoj boraviš kao pridošlica - svu zemlju kanaansku - u vjekovni posjed; a ja ću biti njihov Bog.”"},{"v":9,"t":"Još reče Bog Abrahamu: “A ti Savez čuvaj moj - ti i tvoje potomstvo poslije tebe u sve vijeke."},{"v":10,"t":"A ovo je Savez moj s tobom i tvojim potomstvom poslije tebe koji ćeš vršiti: svako muško među vama neka bude obrezano."},{"v":11,"t":"Obrezujte se, i to neka bude znak Saveza između mene i vas."},{"v":12,"t":"Svako muško među vama, kroz vaša pokoljenja, kad mu se navrši osam dana, neka bude obrezano; i rob, rođen u vašem domu, i onaj što bude kupljen od stranca, koji ne bude od vaše krvi."},{"v":13,"t":"Da, i rob rođen u tvome domu ili za novac kupljen mora se obrezati! Tako će moj Savez na vašem tijelu ostati vječnim Savezom."},{"v":14,"t":"Muško koje se ne bi obrezalo neka se odstrani od svoga roda: takav je prekršio moj Savez.”"},{"v":15,"t":"Još reče Bog Abrahamu: “Tvojoj ženi Saraji nije više ime Saraja: Sara će joj ime biti."},{"v":16,"t":"Nju ću ja blagosloviti i od nje ti dati sina; blagoslov ću na nju izliti te će se narodi od nje razviti; kraljevi će narodima od nje poteći.”"},{"v":17,"t":"Abraham pade ničice pa se nasmija i reče u sebi: “Onome komu je stotinu godina, zar se može roditi dijete? Zar će Sara u devedesetoj rod rađati!”"},{"v":18,"t":"Abraham reče Bogu: “Neka tvojom milošću Jišmael poživi!”"},{"v":19,"t":"A Bog reče: “Ipak će ti tvoja žena Sara roditi sina; nadjeni mu ime Izak. Savez svoj s njime ću sklopiti, Savez vječni s njime i s njegovim potomstvom poslije njega."},{"v":20,"t":"I za Jišmaela uslišah te. Evo ga blagoslivljam: rodnim ću ga učiniti i silno ga razmnožiti; dvanaest će knezova od njega postati i u velik će narod izrasti."},{"v":21,"t":"Ali ću držati svoj Savez s Izakom, koga će ti roditi Sara dogodine u ovo doba.”"},{"v":22,"t":"Kad je završio razgovor s njim, od Abrahama Bog se podiže."},{"v":23,"t":"Uzme zatim Abraham svoga sina Jišmaela i sve robove koji su bili rođeni u njegovu domu i sve koje je kupio novcem - sve muške ukućane - pa ih toga istog dana obreže, kako mu je Bog rekao."},{"v":24,"t":"Abrahamu bijaše devedeset i devet godina kad se obrezao,"},{"v":25,"t":"a njegovu sinu Jišmaelu bijaše trinaest godina kad ga obreza."},{"v":26,"t":"Tako su toga istog dana bili obrezani Abraham i njegov sin Jišmael;"},{"v":27,"t":"i svi muškarci njegova doma, rođeni u njegovoj kući ili za novac kupljeni od stranca - svi s njim bijahu obrezani."}]},"18":{"hr":[{"v":1,"t":"Jahve mu se ukaza kod hrasta Mamre dok je on sjedio na ulazu u šator za dnevne žege."},{"v":2,"t":"Podigavši oči, opazi tri čovjeka gdje stoje nedaleko od njega. Čim ih spazi, potrča s ulaza šatora njima u susret. Pade ničice na zemlju"},{"v":3,"t":"pa reče: “Gospodine moj, ako sam stekao milost u tvojim očima, nemoj mimoići svoga sluge!"},{"v":4,"t":"Nek' se donese malo vode: operite noge i pod stablom otpočinite."},{"v":5,"t":"Donijet ću kruha da se okrijepite prije nego pođete dalje. TÓa k svome ste sluzi navratili.” Oni odgovore: “Dobro, učini kako si rekao!”"},{"v":6,"t":"Abraham se požuri u šator k Sari pa joj reče: “Brzo! Tri mjerice najboljeg brašna! Zamijesi i prevrtu ispeci!”"},{"v":7,"t":"Zatim Abraham otrča govedima, uhvati tele, mlado i debelo, i dade ga momku da ga brže zgotovi."},{"v":8,"t":"Poslije uzme masla, mlijeka i zgotovljeno tele pa stavi pred njih, a sam stajaše pred njima, pod stablom, dok su blagovali."},{"v":9,"t":"“Gdje ti je žena Sara?” - zapitaju ga. “Eno je pod šatorom”, odgovori."},{"v":10,"t":"Onda on reče: “Vratit ću se k tebi kad isteče vrijeme trudnoće; a tvoja žena Sara imat će sina.” Iza njega, na ulazu u šator, Sara je prisluškivala."},{"v":11,"t":"Abraham i Sara bijahu u odmakloj dobi, ostarjeli. U Sare bijaše prestalo što biva u žena."},{"v":12,"t":"Zato se u sebi Sara smijala i govorila: “Pošto sam uvenula, sad da spoznam nasladu? A još mi je i gospodar star!”"},{"v":13,"t":"Onda Jahve upita Abrahama: “A zašto se Sara smijala i govorila: 'Kako ću rod roditi ja starica?'"},{"v":14,"t":"Zar je Jahvi išta nemoguće? Navratit ću se k tebi kad isteče vrijeme trudnoće: Sara će imati sina.”"},{"v":15,"t":"Sara se napravi nevještom govoreći: “Nisam se smijala.” Jer se prestrašila. Ali on reče: “Jesi, smijala si se!”"},{"v":16,"t":"Ljudi ustanu i krenu put Sodome. Abraham pođe s njima da ih isprati."},{"v":17,"t":"Jahve pomisli: “Zar da sakrivam od Abrahama što ću učiniti"},{"v":18,"t":"kad će od Abrahama nastati velik i brojan narod te će se svi narodi zemlje njim blagoslivljati?"},{"v":19,"t":"Njega sam izlučio zato da pouči svoju djecu i svoju buduću obitelj kako će hoditi putem Jahvinim, radeći što je dobro i pravedno, tako da Jahve mogne ostvariti što je Abrahamu obećao.”"},{"v":20,"t":"Onda Jahve nastavi: “Velika je vika na Sodomu i Gomoru da je njihov grijeh pretežak."},{"v":21,"t":"Idem dolje da vidim rade li zaista kako veli tužba što je do mene stigla. Želim razvidjeti.”"},{"v":22,"t":"Odande ljudi krenu prema Sodomi, dok je Abraham još stajao pred Jahvom."},{"v":23,"t":"Nato se Abraham primače bliže i reče: “Hoćeš li iskorijeniti i nevinoga s krivim?"},{"v":24,"t":"Možda ima pedeset nevinih u gradu. Zar ćeš uništiti mjesto radije nego ga poštedjeti zbog pedeset nevinih koji budu ondje?"},{"v":25,"t":"Daleko to bilo od tebe da ubijaš nevinoga kao i krivoga, tako da i nevini i krivi prođu jednako! Daleko bilo od tebe! Zar da ni Sudac svega svijeta ne radi pravo?”"},{"v":26,"t":"“Ako nađem u gradu Sodomi pedeset nevinih”, odvrati Jahve, “zbog njih ću poštedjeti cijelo mjesto.”"},{"v":27,"t":"“Ja se, evo, usuđujem govoriti Gospodinu”, opet progovori Abraham. - “Ja, prah i pepeo!"},{"v":28,"t":"Da slučajno bude nevinih pet manje od pedeset, bi li uništio sav grad zbog tih pet?” “Neću ga uništiti ako ih ondje nađem četrdeset i pet”, odgovori."},{"v":29,"t":"“Ako ih se ondje možda nađe samo četrdeset?” - opet će Abraham. “Neću to učiniti zbog četrdesetorice”, odgovori."},{"v":30,"t":"“Neka se Gospodin ne ljuti ako nastavim. Ako ih se ondje nađe možda samo trideset?” - opet će on. “Neću to učiniti”, odgovori, “ako ih ondje nađem samo trideset.”"},{"v":31,"t":"“Evo se opet usuđujem govoriti Gospodinu”, nastavi dalje. “Ako ih se slučajno ondje nađe samo dvadeset?” “Neću ga uništiti”, odgovori, “zbog dvadesetorice.”"},{"v":32,"t":"“Neka se Gospodin ne ljuti”, on će opet, “ako rečem još samo jednom: Ako ih je slučajno ondje samo deset?” “Neću ga uništiti zbog njih deset”, odgovori."},{"v":33,"t":"Kad je Jahve završio razgovor s Abrahamom, ode, a Abraham se vrati u svoje mjesto."}]},"19":{"hr":[{"v":1,"t":"Ona dva anđela stignu navečer u Sodomu dok je Lot sjedio na vratima Sodome. Kad ih Lot ugleda, ustade i pođe im u susret. Nakloni se licem do zemlje,"},{"v":2,"t":"a onda im reče: “Molim, gospodo, svrnite u kuću svoga sluge da noć provedete i noge operete; a onda možete na put rano.” A oni rekoše: “Ne, noć ćemo provesti na trgu.”"},{"v":3,"t":"Ali ih on uporno navraćaše, i oni se uvratiše k njemu i uđoše u njegovu kuću. On ih ugosti, ispeče pogaču te blagovaše."},{"v":4,"t":"Još ne bijahu legli na počinak, kad građani Sodome, mladi i stari, sav narod do posljednjeg čovjeka, opkole kuću."},{"v":5,"t":"Zovnu Lota pa mu reknu: “Gdje su ljudi što su noćas došli k tebi? Izvedi nam ih da ih se namilujemo?”"},{"v":6,"t":"Lot iziđe k njima na ulaz, a za sobom zatvori vrata."},{"v":7,"t":"“Braćo moja,” reče on, “molim vas, ne činite toga zla!"},{"v":8,"t":"Imam, evo, dvije kćeri s kojima još čovjek nije imao dodira: njih ću vam izvesti pa činite s njima što želite; samo ovim ljudima nemojte ništa učiniti jer su došli pod sjenu moga krova.”"},{"v":9,"t":"“Odstupi odatle!” - rekoše. - “Došao kao dotepenac, a za suca se već postavlja. Sad ćemo mi s tobom gore nego s njima.” I nasrnuše na jadnika Lota i navališe na vrata da ih razbiju."},{"v":10,"t":"Ali ona dvojica pruže ruke van, povukoše Lota k sebi u kuću i zatvore vrata;"},{"v":11,"t":"a ljude pred vratima, mlade i stare, zabliješte tako da nisu mogli naći vrata."},{"v":12,"t":"Onda ona dvojica upitaju Lota: “Koga još ovdje imaš: sinove i kćeri, sve koje imaš u gradu iz mjesta izvedi!"},{"v":13,"t":"Jer mi ćemo zatrti ovo mjesto: vika je na njih pred Jahvom postala tolika te nas Jahve posla da ga uništimo.”"},{"v":14,"t":"Iziđe Lot da to kaže svojima budućim zetovima koji namjeravahu uzeti njegove kćeri te reče: “Na noge! Odlazite iz ovog mjesta jer će Jahve uništiti grad!” Ali je u očima svojih budućih zetova ispao kao da zbija šalu."},{"v":15,"t":"Kako zora puče, anđeli navale na Lota govoreći: “Na noge! Uzmi svoju ženu i svoje dvije kćeri koje su ovdje da ne budeš zatrt kaznom grada!”"},{"v":16,"t":"Ali on oklijevaše. Zato ga oni uzeše za ruku, a tako i njegovu ženu i njegove dvije kćeri i - po smilovanju Jahvinu nad njim - odvedoše ih i ostaviše izvan grada."},{"v":17,"t":"Kad ih izvedoše u polje, jedan progovori: “Bježi da život spasiš! Ne obaziri se niti se igdje u ravnici zaustavljaj! Bježi u brdo da ne budeš zatrt!”"},{"v":18,"t":"Ali Lot odvrati: “Nemoj, gospodine!"},{"v":19,"t":"Nego ako je tvoj sluga našao milost u tvojim očima - a toliko milosrđe već si mi iskazao spasivši mi život - ja ne mogu pobjeći u brdo a da me nesreća ne snađe i ne poginem."},{"v":20,"t":"Eno onamo grada; dosta je blizu da u nj pobjegnem, a mjesto je tako malo. Daj da onamo bježim - mjesto je zbilja maleno - daj da život spasim!”"},{"v":21,"t":"Odgovori mu: “Uslišat ću ti i tu molbu i neću zatrti grada o kojemu govoriš."},{"v":22,"t":"Brzo! Bježi onamo, jer ne mogu ništa činiti dok ti onamo ne stigneš.” Zato se onaj grad zove Soar."},{"v":23,"t":"Kako je sunce na zemlju izlazilo i Lot ulazio u Soar,"},{"v":24,"t":"Jahve zapljušti s neba na Sodomu i Gomoru sumpornim ognjem"},{"v":25,"t":"i uništi one gradove i svu onu ravnicu, sve žitelje gradske i sve raslinstvo na zemlji."},{"v":26,"t":"A Lotova se žena obazre i pretvori se u stup soli."},{"v":27,"t":"Sutradan u rano jutro Abraham se požuri na mjesto gdje je stajao pred Jahvom,"},{"v":28,"t":"upravi pogled prema Sodomi i Gomori i svoj ravnici u daljini: i vidje kako se diže dim nad zemljom kao dim kakve klačine."},{"v":29,"t":"Tako se Bog, dok je zatirao gradove u ravnici u kojima je Lot boravio, sjetio Abrahama i uklonio Lota ispred propasti."},{"v":30,"t":"Lot se bojao boraviti u Soaru, pa sa svoje dvije kćeri ode gore iz Soara i nastani se u brdu. On i njegove dvije kćeri živjeli su u pećini."},{"v":31,"t":"Starija reče mlađoj: “Otac nam ostarje, a muža na zemlji nema da bude s nama, kako je običaj po svem svijetu."},{"v":32,"t":"Hajdemo oca opiti vinom, pa s njime leći: tako ćemo s ocem sačuvati potomstvo.”"},{"v":33,"t":"One noći opiju oca vinom, i starija ode te legne sa svojim ocem, a on nije znao kad je legla ni kad je ustala."},{"v":34,"t":"Sutradan starija reče mlađoj: “Sinoć sam, eto, ležala ja s našim ocem; napojimo ga vinom i noćas, pa idi ti i s njim lezi: tako ćemo ocu sačuvati potomstvo.”"},{"v":35,"t":"Opiju oca vinom i one noći te mlađa ode i s njim legne, a on nije znao kad je legla ni kad je ustala."},{"v":36,"t":"Tako obje Lotove kćeri zanesu s ocem."},{"v":37,"t":"Starija rodi sina i nadjenu mu ime Moab. On je praotac današnjih Moabaca."},{"v":38,"t":"I mlađa rodi sina i nadjene mu ime Ben-Ami. On je praotac današnjih Amonaca."}]},"20":{"hr":[{"v":1,"t":"Odande Abraham krene u krajeve Negeba i nastani se između Kadeša i Šura. Dok je boravio kao pridošlica u Geraru,"},{"v":2,"t":"rekao je Abraham za svoju ženu Saru da mu je sestra. I Abimelek, kralj gerarski, uze Saru sebi."},{"v":3,"t":"Ali Bog dođe Abimeleku noću u snu te mu reče: “Zbog žene koju si uzeo moraš umrijeti, jer je ona žena udata.”"},{"v":4,"t":"A nije se Abimelek k njoj približavao. Zato reče: “Gospodine, zar ćeš pravednika pogubiti?"},{"v":5,"t":"Zar mi on nije rekao: 'Ona mi je sestra.' A ona mi je sama rekla: 'On je moj brat.' Čiste sam savjesti i neokaljanih ruku ovo učinio.”"},{"v":6,"t":"Bog mu odvrati u snu: “Znam da si to učinio čiste savjesti; i ja sam te zadržavao da protiv mene ne griješiš; i nisam dopuštao da je dotakneš."},{"v":7,"t":"Sada vrati čovjeku ženu njegovu; prorok je on; molit će se za tebe da ostaneš na životu. Ako je ne vratiš, znaj da ćeš umrijeti, ti i svi tvoji.”"},{"v":8,"t":"Rano ujutro Abimelek ustane, sazove sve svoje sluge i kaže im sve što je bilo, a ljudi se veoma uplaše."},{"v":9,"t":"Potom Abimelek dozva Abrahama te mu reče: “Što si nam učinio! Čime sam se ja ogriješio prema tebi da izložiš mene i moje kraljevstvo velikoj grehoti? Ponio si se prema meni kako ne valja."},{"v":10,"t":"Što si, dakle na umu imao”, upita dalje Abimelek, “kad si tako radio?”"},{"v":11,"t":"Abraham uzvrati: “Zbilja sam držao da nema Božjeg straha u ovome mjestu, pa će me ljudi ubiti zbog moje žene."},{"v":12,"t":"A onda, ona je uistinu moja sestra: kći je moga oca, iako ne i moje majke, pa je pošla za me."},{"v":13,"t":"A kad me Bog udaljio od doma očeva, rekoh joj: Ovu mi uslugu učini: kamo god dođemo, reci o meni da sam ti brat.”"},{"v":14,"t":"Abimelek uzme ovaca i goveda, sluga i sluškinja pa ih dade Abrahamu; vrati mu i njegovu ženu Saru."},{"v":15,"t":"Abimelek zatim reče: “Evo, moja ti je zemlja otvorena. Nastani se gdje ti se svidi!”"},{"v":16,"t":"A Sari reče: “Evo tisuću srebrnika što ih dajem tvome bratu: neka ti budu koprenom pred očima sviju što su s tobom. Ti si svakako opravdana.”"},{"v":17,"t":"Abraham se pomoli Bogu, i Bog ozdravi Abimeleka, njegovu ženu i njegove sluškinje, tako te opet mogahu rađati."},{"v":18,"t":"Jer Jahve bijaše zbog Sare, Abrahamove žene, zatvorio svaku utrobu u domu Abimelekovu."}]},"21":{"hr":[{"v":1,"t":"Jahve se sjeti Sare kako je rekao i učini joj kako je obećao:"},{"v":2,"t":"Sara zače i rodi Abrahamu sina u njegovoj starosti - u vrijeme koje je Bog označio."},{"v":3,"t":"Abraham nadjene ime Izak svome sinu što mu ga Sara rodi."},{"v":4,"t":"I poslije osam dana obreza Abraham svoga sina Izaka, kako mu je Bog naredio."},{"v":5,"t":"Abrahamu bijaše stotinu godina kad mu se rodio sin Izak."},{"v":6,"t":"Sara reče: “Dade mi Bog da se nasmijem, i tko god to čuje nasmijat će mi se.”"},{"v":7,"t":"Još doda: “Tko bi ikad rekao Abrahamu: djecu će ti Sara dojiti! Ipak sina mu rodih u starosti”."},{"v":8,"t":"Dijete je raslo i bilo od sise odbijeno. A u dan u koji Izak bijaše od sise odbijen Abraham priredi veliku gozbu."},{"v":9,"t":"Jednom opazi Sara gdje se sin koga je Egipćanka Hagara Abrahamu rodila igra s njezinim sinom Izakom,"},{"v":10,"t":"pa reče Abrahamu: “Otjeraj tu sluškinju i njezina sina, jer sin sluškinje ne smije biti baštinik s mojim sinom - s Izakom!”"},{"v":11,"t":"To je Abrahamu bilo nemilo, jer je i Jišmael bio njegov sin."},{"v":12,"t":"Ali Bog reče Abrahamu: “Nemoj se uznemirivati zbog dječaka i zbog svoje sluškinje; sve što ti kaže Sara poslušaj, jer će Izakovo potomstvo tebi ovjekovječiti ime."},{"v":13,"t":"I od sina tvoje sluškinje podići ću velik narod, jer je tvoj potomak.”"},{"v":14,"t":"Rano ujutro Abraham uze kruha i mješinicu vode pa dade Hagari; stavi to na njezina ramena, zajedno s dječakom, te je otpusti. Vrludala je amo-tamo po pustinji Beer Šebe."},{"v":15,"t":"Potrošivši vodu iz mješinice, ostavi dijete pod jednim grmom,"},{"v":16,"t":"a sama ode i sjede nasuprot, daleko koliko luk može dobaciti. Govorila je u sebi: “Neću da vidim kako dijete umire.” Sjedeći tako, udari u jecanje."},{"v":17,"t":"Bog ču plač dječaka te anđeo Božji zovne s neba Hagaru i reče joj: “Što ti je, Hagaro? Ne boj se! Jer je Bog čuo plač dječaka u njegovoj nevolji."},{"v":18,"t":"Na noge! Digni dječaka i utješi ga, jer od njega ću podići velik narod.”"},{"v":19,"t":"Tada joj Bog otvori oči pa ona opazi studenac. Ode i napuni vodom mješinicu pa napoji dječaka."},{"v":20,"t":"Bog je bio s dječakom te je rastao i odrastao. Živio je u pustinji te postao vješt u strijeljanju iz luka."},{"v":21,"t":"Dom mu bijaše u pustinji Paranu; a njegova mu majka dobavi ženu iz zemlje egipatske."},{"v":22,"t":"U to vrijeme Abimelek - koga je pratio Fikol, zapovjednik njegove vojske - reče Abrahamu: “Bog je s tobom u svemu što radiš."},{"v":23,"t":"Stoga mi se ovdje i sada zakuni Bogom da nećeš varati ni mene ni moju rodbinu i prijatelje nego da ćeš se prema meni i prema zemlji u kojoj sad boraviš ponašati pošteno, kao što sam se ja prema tebi ponio.”"},{"v":24,"t":"“Kunem se”, odgovori Abraham."},{"v":25,"t":"Onda Abraham prekori Abimeleka zbog zdenca vode što su ga Abimelekove sluge bile prisvojile."},{"v":26,"t":"A Abimelek reče: “Ne znam tko je to učinio; ni ti me nisi o tome obavijestio, niti sam ja o tome čuo, osim danas.”"},{"v":27,"t":"Abraham uzme ovaca i goveda pa ih dade Abimeleku te njih dvojica sklope savez."},{"v":28,"t":"Potom Abraham razluči napose sedam janjaca od stada."},{"v":29,"t":"Nato Abimelek zapita Abrahama: “Što znači ovih sedam janjaca koje si na stranu stavio?”"},{"v":30,"t":"A on odgovori: “Primi ovih sedam janjaca iz moje ruke da mi bude dokazom da sam ja iskopao ovaj zdenac.”"},{"v":31,"t":"Zato se ono mjesto nazvalo Beer Šeba; jer se njih dvojica ondje zakleše."},{"v":32,"t":"Pošto su sklopili savez kod Beer Šebe, Abimelek i zapovjednik njegove vojske Fikol odu i vrate se u zemlju Filistejaca."},{"v":33,"t":"Abraham zasadi kod Beer Šebe tamarisku i ondje zazove ime Jahve - Boga Vječnoga."},{"v":34,"t":"Dugo je vremena Abraham proveo u zemlji filistejskoj kao pridošlica."}]},"22":{"hr":[{"v":1,"t":"Poslije tih događaja Bog stavi Abrahama na kušnju. Zovnu ga: “Abrahame!” On odgovori: “Evo me!”"},{"v":2,"t":"Bog nastavi: “Uzmi svoga sina, jedinca svoga Izaka koga ljubiš, i pođi u krajinu Moriju pa ga ondje prinesi kao žrtvu paljenicu na brdu koje ću ti pokazati.”"},{"v":3,"t":"Ujutro Abraham podrani, osamari magarca, sa sobom povede dvojicu svojih slugu i svog sina Izaka, pošto je prije nacijepao drva za žrtvu paljenicu, i uputi se na mjesto koje mu je Bog označio."},{"v":4,"t":"Treći dan Abraham podigne oči i opazi mjesto izdaleka."},{"v":5,"t":"Abraham onda reče slugama: “Vi ostanite ovdje uz magarca, a ja i dječak odosmo gore da se poklonimo, pa ćemo se vratiti k vama”."},{"v":6,"t":"Abraham uzme drva za žrtvu paljenicu, stavi ih na sina Izaka, a u svoju ruku uzme kremen i nož. Tako pođu obojica zajedno."},{"v":7,"t":"Onda Izak reče svome ocu Abrahamu: “Oče!” “Evo me, sine!” - javi se on. “Evo kremena i drva,” opet će sin, “ali gdje je janje za žrtvu paljenicu?”"},{"v":8,"t":"“Bog će već providjeti janje za žrtvu paljenicu, sine moj!” - odgovori Abraham. I nastave put."},{"v":9,"t":"Stignu na mjesto o kojemu je Bog govorio. Ondje Abraham podigne žrtvenik, naslaže drva, sveže svog sina Izaka i položi ga po drvima na žrtvenik."},{"v":10,"t":"Pruži sad Abraham ruku i uzme nož da zakolje svog sina."},{"v":11,"t":"Uto ga zovne s neba anđeo Jahvin i poviče: “Abrahame! Abrahame!” “Evo me!” - odgovori on."},{"v":12,"t":"“Ne spuštaj ruku na dječaka”, reče, “niti mu što čini! Sad, evo, znam da se Boga bojiš, jer nisi uskratio ni svog sina, jedinca svoga.”"},{"v":13,"t":"Podiže Abraham oči i pogleda, i gle - za njim ovan, rogovima se zapleo u grmu. Tako Abraham ode, uzme ovna i prinese ga za žrtvu paljenicu mjesto svoga sina."},{"v":14,"t":"Onome mjestu Abraham dade ime “Jahve proviđa”. Zato se danas veli: “Na brdu Jahvina proviđanja.”"},{"v":15,"t":"Anđeo Jahvin zovne Abrahama s neba drugi put"},{"v":16,"t":"i reče: “Kunem se samim sobom, izjavljuje Jahve: Kad si to učinio i nisi mi uskratio svog jedinca sina,"},{"v":17,"t":"svoj ću blagoslov na te izliti i učiniti tvoje potomstvo brojnim poput zvijezda na nebu i pijeska na obali morskoj! A tvoji će potomci osvajati vrata svojih neprijatelja."},{"v":18,"t":"Budući da si poslušao moju zapovijed, svi će se narodi zemlje blagoslivljati tvojim potomstvom.”"},{"v":19,"t":"Zatim se Abraham vrati k svojim slugama pa se zajedno upute u Beer Šebu. U Beer Šebi se Abraham nastani."},{"v":20,"t":"Poslije tih događaja obavijeste Abrahama: “I tvome bratu Nahoru Milka je porodila djecu:"},{"v":21,"t":"njegova prvorođenca Usa, brata mu Buza i Kemuela - oca Aramova,"},{"v":22,"t":"Keseda, Haza, Pildaša, Jidlafa i Betuela.”"},{"v":23,"t":"Betuel je bio otac Rebekin. Njih je osam rodila Milka Nahoru, Abrahamovu bratu."},{"v":24,"t":"A i njegova suložnica, kojoj bijaše ime Reuma, rodila je Tebaha, Gahama, Tahaša i Maaku."}]},"23":{"hr":[{"v":1,"t":"Duljina Sarina života bila je stotinu dvadeset i sedam godina."},{"v":2,"t":"Sara umrije u Kirjat Arbi, to jest u Hebronu, u zemlji kanaanskoj; i Abraham uđe u žalost za Sarom i naricaše za njom."},{"v":3,"t":"Potom se Abraham digne ispred svoje pokojnice te prozbori sinovima Hetovim:"},{"v":4,"t":"“Premda sam ja među vama doseljeni stranac, prodajte mi zemljište za grob među vama, tako da mogu iznijeti svoju pokojnicu i sahraniti je.”"},{"v":5,"t":"A sinovi Hetovi odgovore Abrahamu:"},{"v":6,"t":"“Gospodine, saslušaj nas! Ti si izabranik Božji u našoj sredini. Pokopaj svoju pokojnicu u našem najbiranijem grobu. Nitko ti od nas neće odbiti svoga groba da mogneš sahraniti svoju pokojnicu.”"},{"v":7,"t":"Nato se Abraham diže pa se mještanima, sinovima Hetovim, duboko pokloni"},{"v":8,"t":"te im reče: “Ako se slažete da svoju pokojnicu uklonim i sahranim, čujte me: zauzmite se za me kod Efrona, sina Soharova,"},{"v":9,"t":"da mi proda spilju Makpelu što njemu pripada a nalazi se na kraju njegova posjeda; neka mi je za punu cijenu, u vašoj nazočnosti, proda u vlasništvo za sahranjivanje.”"},{"v":10,"t":"A Efron je sjedio sa sinovima Hetovim. Potom Efron, Hetit, odgovori Abrahamu da ga čuju sinovi Hetovi svojim ušima - svi koji su sjedili u vijeću onoga grada:"},{"v":11,"t":"“Ne, moj gospodine! Saslušaj mene! Ja tebi dajem poljanu i spilju što je na njoj; darujem ti to pred sinovima svoga naroda. Sahrani svoju pokojnicu.”"},{"v":12,"t":"Abraham se duboko nakloni mještanima,"},{"v":13,"t":"a onda progovori Efronu da mještani čuju na svoje uši: “Ded me samo poslušaj! Dajem ti cijenu za poljanu; primi je od mene da ondje mogu sahraniti svoju pokojnicu!”"},{"v":14,"t":"Efron odgovori Abrahamu:"},{"v":15,"t":"“Čuj me, moj gospodine: zemljište u vrijednosti od četiri stotine srebrnika, što je to tebi i meni! Sahrani, dakle, svoju pokojnicu!”"},{"v":16,"t":"Abraham se složi s Efronom; isplati Abraham Efronu novac što ga je spomenuo tako da su na svoje uši čuli sinovi Hetovi - četiri stotine srebrnika trgovačke mjere."},{"v":17,"t":"I tako Efronova poljana u Makpeli nasuprot Mamri - poljana, spilja i sva stabla što su bila na poljani -"},{"v":18,"t":"prijeđe u vlasništvo Abrahamovo u nazočnosti sinova Hetovih, sviju koji su sjedili u vijeću svoga grada."},{"v":19,"t":"A onda Abraham sahrani svoju ženu Saru u spilji na poljani Makpeli nasuprot Mamri - danas Hebronu - u zemlji kanaanskoj."},{"v":20,"t":"Tako je poljana i spilja na njoj prešla od sinova Hetovih u vlasništvo Abrahamovo za sahranjivanje."}]},"24":{"hr":[{"v":1,"t":"Abraham bijaše već ostario, zašao u godine, Jahve je Abrahama blagoslovio u svemu."},{"v":2,"t":"Abraham prozbori svome najstarijem sluzi u kući, pod čijom je upravom bilo sve njegovo: “Stavi svoju ruku pod moje stegno"},{"v":3,"t":"da te zakunem Jahvom, Bogom neba i Bogom zemlje, da mome sinu nećeš nabaviti za ženu ni jednu od kćeri Kanaanaca, među kojima boravim,"},{"v":4,"t":"nego ćeš otići u moj rodni kraj i dobaviti ženu mom sinu Izaku.”"},{"v":5,"t":"A sluga mu reče: “A što ako žena ne htjedne za mnom ići u ovu zemlju? Hoću li ja onda odvesti tvoga sina u zemlju iz koje si ti došao?”"},{"v":6,"t":"Abraham mu odgovori: “Dobro pripazi da onamo ne vodiš moga sina!"},{"v":7,"t":"Jahve, Bog nebesa, koji me odveo iz kuće moga oca i rodnog kraja i koji mi je pod zakletvom obećao: 'Tvome ću potomstvu dati ovu zemlju', pred tobom će poslati svog anđela, i odande ćeš ti dovesti ženu mome sinu."},{"v":8,"t":"A ako žena ne bude htjela za tobom poći, ti ćeš biti oslobođen od ove moje zakletve; ali moga sina onamo ne vodi!”"},{"v":9,"t":"Tako sluga stavi svoju ruku pod stegno Abrahamu, svom gospodaru, te mu se zakune."},{"v":10,"t":"Sluga opremi deset gospodarevih deva, ponese sa sobom svakog blaga svoga gospodara pa se zaputi u Aram Naharajim, u Nahorov grad."},{"v":11,"t":"Pusti deve da poliježu izvan grada, pokraj studenca. Bijaše večer, kad žene izlaze da crpu vodu."},{"v":12,"t":"Onda reče: “Oh, Jahve, Bože moga gospodara Abrahama, molim te, iziđi mi danas u susret i mome gospodaru Abrahamu milost iskaži!"},{"v":13,"t":"Evo me kraj studenca, a kćeri onih iz grada dolaze crpsti vodu;"},{"v":14,"t":"pa neka djevojka kojoj ja rečem: 'Molim te, spusti svoj vrč da se napijem', a ona odgovori: 'Pij! I deve ću ti napojiti', bude ona koju si odredio za svoga slugu Izaka. Tako ću saznati da si iskazao milost mome gospodaru.”"},{"v":15,"t":"Tek što on izreče svoje, gle, dođe Rebeka, kći Betuelova; taj Betuel bijaše sin Milke, žene Abrahamova brata Nahora. Dođe ona s krčagom na ramenu."},{"v":16,"t":"Djevojka je bila krasna, djevica koju muškarac nije dirnuo. Siđe ona k vrelu, napuni krčag i eto je opet gore."},{"v":17,"t":"Sluga joj potrča u susret i reče: “Daj mi malo vode iz svog vrča!”"},{"v":18,"t":"“Pij, gospodine!” - odgovori ona. Brzo spusti krčag na ruku i dade mu piti."},{"v":19,"t":"Kad je njega napojila, reče: “Nalit ću i tvojim devama da se napoje.”"},{"v":20,"t":"Izlivši brzo krčag u korito, otrča natrag zdencu da ponovo zahvaća, i tako nali svim njegovim devama."},{"v":21,"t":"Čovjek ju je šutke motrio ne bi li saznao je li Jahve njegov put uspješno priveo kraju ili nije."},{"v":22,"t":"Kad su deve prestale piti, čovjek izvadi viticu od zlata, tešku pol šekela, i stavi je na njezine nosnice, a na ruke joj stavi dvije zlatne narukvice, teške deset šekela."},{"v":23,"t":"Zatim reče: “Kaži mi čija si kći. Ima li u kući tvoga oca mjesta za nas da prenoćimo?”"},{"v":24,"t":"Ona mu odgovori: “Ja sam kći Betuela, koga je Milka rodila Nahoru.”"},{"v":25,"t":"Još mu doda: “Ima slame i p§iće kod nas u obilju, a i mjesta za prenoćište.”"},{"v":26,"t":"Čovjek se onda duboko nakloni te iskaže poštovanje Jahvi"},{"v":27,"t":"i progovori: “Neka je blagoslovljen Jahve, Bog moga gospodara Abrahama, što nije uskratio svoju ljubav i svoju vjernost mome gospodaru. Mene je Jahve vodio pravim putem, u kuću brata moga gospodara.”"},{"v":28,"t":"Djevojka otrča i sve ovo ispripovjedi u kući svoje majke."},{"v":29,"t":"A Rebeka imala brata komu bijaše ime Laban. Laban se požuri van, k čovjeku kod studenca."},{"v":30,"t":"Čim je vidio nosnu viticu i narukvice na rukama svoje sestre te čuo kako je njegova sestra Rebeka rekla: “Ovako mi je čovjek govorio”, on pođe onome koji je još stajao kod deva na studencu."},{"v":31,"t":"Reče on: “Hajde unutra, blagoslovljeni od Jahve! Što stojiš vani kad sam ja spremio kuću i mjesto za deve.”"},{"v":32,"t":"Tako čovjek uđe u kuću. Rastovare deve i dadu im slame i p§iće, a njemu i ljudima koji su ga pratili donesu vode da operu noge."},{"v":33,"t":"Ali kad su preda nj stavili hranu, reče: “Neću jesti dok ne kažem što imam kazati.” A Laban mu reče: “Onda kazuj!”"},{"v":34,"t":"“Ja sam sluga Abrahamov”, poče on."},{"v":35,"t":"“Jahve je uvelike blagoslovio moga gospodara te je postao bogat. Nadavao mu je ovaca i goveda, srebra i zlata, sluga i sluškinja, deva i magaradi."},{"v":36,"t":"Sara, žena moga gospodara, rodi mu sina pošto je ostarjela, i on mu ustupi sve svoje."},{"v":37,"t":"Potom mene moj gospodar zakune rekavši: 'Nemoj uzeti za ženu mome sinu djevojku Kanaanku, u zemlji u kojoj boravim kao stranac,"},{"v":38,"t":"nego otiđi k obitelji moga oca, k mojoj rodbini, da nađeš ženu mome sinu.'"},{"v":39,"t":"A ja rekoh svome gospodaru: 'A što ako žena za mnom ne pođe?'"},{"v":40,"t":"On mi odgovori: 'Jahve, pred čijim sam licem hodio, poslat će s tobom svog anđela i tvoje će putovanje dovesti k cilju, a ti ćeš naći ženu mome sinu od moje rodbine, od obitelji moga oca."},{"v":41,"t":"Jedino ćeš ovako biti oslobođen moje zakletve: ako dođeš k mojoj rodbini, i oni te odbiju, od moje si zakletve oslobođen.'"},{"v":42,"t":"Danas dođoh na studenac i rekoh: 'Jahve, Bože moga gospodara Abrahama, ako si voljan da uspješno završim putovanje što sam ga poduzeo,"},{"v":43,"t":"ja, evo, stojim kraj studenca, a djevojka koja dođe vodu crpsti i ja joj rečem: Daj mi da se napijem malo vode iz tvog vrča! -"},{"v":44,"t":"i koja mi kaže: Pij ti, a i tvojim ću devama zahvatiti! - ona neka bude žena koju je Jahve odredio sinu moga gospodara.'"},{"v":45,"t":"Tek što sam ja završio govor u sebi, kad se, evo, pojavi Rebeka s vrčem na ramenu; siđe k izvoru i zahvati. Ja joj rekoh: 'Daj mi da se napijem!'"},{"v":46,"t":"Ona brzo spusti vrč i odvrati: 'Pij! A napojit ću i tvoje deve.' Tako sam se ja napio, a ona napoji i moje deve."},{"v":47,"t":"Pitao sam je: 'Čija si kći?' Odgovorila je: 'Kći sam Betuela, koga je Nahoru rodila Milka.' Tada joj stavim viticu na nos a narukvice na ruke."},{"v":48,"t":"Duboko se naklonim i štovanje Jahvi iskažem te blagoslovim Jahvu, Boga gospodara moga, koji me vodio pravim putem da uzmem kćer brata moga gospodara njegovu sinu."},{"v":49,"t":"A sad, ako kanite iskazati ljubav i vjernost mome gospodaru, recite mi; ako li ne, to mi kažite, tako da mogu krenuti bilo desno bilo lijevo.”"},{"v":50,"t":"Tada odgovore Laban i Betuel: “Od Jahve to dolazi; mi tu ne možemo reći ni da ni ne."},{"v":51,"t":"Rebeka je, eto, pred tobom: uzmi je pa idi, neka bude ženom sinu tvoga gospodara, kako je Jahve rekao.”"},{"v":52,"t":"Kad Abrahamov sluga ču njihov pristanak, do zemlje se nakloni Jahvi."},{"v":53,"t":"Sluga zatim izvadi srebrnih i zlatnih predmeta te haljina i dade ih Rebeki, a dade darova i njezinu bratu i majci."},{"v":54,"t":"Tada jedoše i piše on i ljudi koji su bili s njim i provedoše noć. Kad su ujutro ustali, on reče: “Pustite me da se vratim svome gospodaru!”"},{"v":55,"t":"A njezin brat i majka odgovore: “Neka djevojka ostane s nama još desetak dana, pa poslije toga pođi!”"},{"v":56,"t":"On im reče: “Ne zadržavajte me kad je Jahve moje putovanje uspješno kraju priveo. Pustite me da se vratim svome gospodaru!”"},{"v":57,"t":"Oni odgovore: “Pozovimo djevojku i upitajmo što ona misli!”"},{"v":58,"t":"Dozovu Rebeku pa je upitaju: “Hoćeš li poći s ovim čovjekom?” Ona odgovori: “Hoću.”"},{"v":59,"t":"I tako otpreme svoju sestru Rebeku i njezinu dojilju s Abrahamovim slugom i njegovim ljudima."},{"v":60,"t":"Blagoslove Rebeku i reknu joj: “Sejo naša, budi mati nebrojenim tisućama, a dušmana svojih vrata potomci ti zaposjeli!”"},{"v":61,"t":"Onda se diže Rebeka i njezine dvorkinje, zajahaše deve te pođoše za čovjekom. Tako sluga preuze Rebeku i ode."},{"v":62,"t":"Izak se vratio iz blizine Beer Lahaj Roja; živio je, naime, u kraju Negeba."},{"v":63,"t":"U predvečerje iziđe Izak da se poljem prošeta; diže oči i ugleda deve gdje dolaze."},{"v":64,"t":"Kad Rebeka, podigavši svoje oči, opazi Izaka, sjaha s deve"},{"v":65,"t":"pa zapita slugu: “Tko je onaj čovjek što poljem ide nama u susret?” A sluga odgovori: “Ono je moj gospodar.” Nato ona uze koprenu te se pokri."},{"v":66,"t":"Sluga ispriča Izaku sve što je učinio."},{"v":67,"t":"Tada Izak uvede Rebeku u svoj šator i uze je sebi za ženu. U ljubavi prema njoj Izak je nalazio utjehu nakon smrti svoje majke."}]},"25":{"hr":[{"v":1,"t":"Abraham je sebi uzeo još jednu ženu; zvala se Ketura."},{"v":2,"t":"Ona mu je rodila Zimrana, Jokšana, Medana, Midjana, Jišbaka i Šuaha."},{"v":3,"t":"A od Jokšana rodili se Šeba i Dedan. Dedanovi su potomci: Ašurci, Letušci i Leumci."},{"v":4,"t":"Sinovi su Midjanovi: Efa, Efer, Hanok, Abida i Eldaa. Sve su to potomci Keturini."},{"v":5,"t":"Abraham prenese sav svoj imutak na Izaka;"},{"v":6,"t":"a sinovima od svojih suložnica dade Abraham samo darove i još ih za svoga života razašalje po istoku - daleko od svog sina Izaka - u Istočni kraj."},{"v":7,"t":"Ovo je duljina Abrahamova života što ga je proživio: stotinu sedamdeset i pet godina."},{"v":8,"t":"Zatim Abraham preminu, umrije u sretnoj dobi - star i pun godina - te bi pridružen svojim precima."},{"v":9,"t":"Njegovi sinovi, Izak i Jišmael, sahrane ga u spilji Makpeli, na poljani Efrona, sina Hetita Sohara, nasuprot Mamri:"},{"v":10,"t":"to je poljana što ju je Abraham kupio od Hetovih sinova. Ondje je sahranjen Abraham i njegova žena Sara."},{"v":11,"t":"Poslije Abrahamove smrti Bog je blagoslivljao njegova sina Izaka. Izak je živio blizu Beer Lahaj Roja."},{"v":12,"t":"Ovo je povijest Abrahamova sina Jišmaela, koga je Abrahamu rodila Sarina sluškinja, Egipćanka Hagara."},{"v":13,"t":"A ovo su sinovi Jišmaelovi, svaki po svom imenu i po svom rođenju: Jišmaelov prvenac Nebajot, Kedar, Adbeel, Mibsam,"},{"v":14,"t":"Mišma, Duma, Masa,"},{"v":15,"t":"Hadad, Tema, Jetur, Nafiš i Kedma."},{"v":16,"t":"To su Jišmaelovi sinovi i to su njihova imena prema njihovim naseljima i taborištima: dvanaest poglavica od isto toliko plemena."},{"v":17,"t":"A ovo je duljina Jišmaelova života: stotinu trideset i sedam godina. Zatim izdahnu; umrije i bi pridružen svojim precima."},{"v":18,"t":"Potomstvo mu se naselilo od Havile do Šura, koji je na istok Egiptu idući prema Ašuru. Nastaniše se nasuprot svojoj braći."},{"v":19,"t":"Ovo je povijest Abrahamova sina Izaka: Izak se rodio od Abrahama."},{"v":20,"t":"Izaku je bilo četrdeset godina kad se oženio Rebekom, kćerkom Aramejca Betuela iz Padan Arama, a sestrom Aramejca Labana."},{"v":21,"t":"Izak se obrati Jahvi za svoju ženu jer je bila nerotkinja. Jahve ga usliša te njegova žena Rebeka zače."},{"v":22,"t":"No djeca se u njezinoj utrobi tako sudarala te ona uzviknu: “Ako je tako, zašto ću živjeti!” Ode, dakle, da se posavjetuje s Jahvom."},{"v":23,"t":"I Jahve joj reče: “Dva su svijeta u utrobi tvojoj; dva će se naroda iz tvog krila odijeliti. Narod će nad narodom gospodovati, stariji će služiti mlađemu.”"},{"v":24,"t":"Došlo vrijeme da rodi, kad gle - blizanci u njezinoj utrobi."},{"v":25,"t":"Pojavi se prvi. Bio je crven; sav runjav kao ogrtač. Stoga mu nadjenuše ime Ezav."},{"v":26,"t":"Potom se pojavi njegov brat. Rukom se držao Ezavu za petu. Zato mu nadjenuše ime Jakov. Izaku je bilo šezdeset godina kad su oni rođeni."},{"v":27,"t":"Kad su dječaci odrasli, Ezav postane vješt lovac, čovjek pustare. Jakov je bio čovjek krotak i boravio je u šatorima."},{"v":28,"t":"Izaku je Ezav bio draži jer je volio divljač, a Rebeka je više voljela Jakova."},{"v":29,"t":"Jednom Jakov kuhaše jelo. Ezav stigne s polja, gladan."},{"v":30,"t":"Reče Ezav Jakovu: “Daj mi toga crvenog variva da pojedem jer sam izgladnio.” Stoga mu je ime Edom."},{"v":31,"t":"A Jakov odgovori: “Ustupi mi prije svoje prvorodstvo!”"},{"v":32,"t":"Ezav reče: “Evo me skoro na smrti; što će mi prvorodstvo!”"},{"v":33,"t":"Jakov nastavi: “Prije mi se zakuni!” On mu se zakune, i tako proda Jakovu svoje prvorodstvo."},{"v":34,"t":"Tada Jakov dade Ezavu kruha i čorbe od sočivice. Jeo je i pio, onda se digao i otišao. Tako Ezav pogazi svoje prvorodstvo."}]},"26":{"hr":[{"v":1,"t":"U zemlji zavlada glad, različita od prijašnje što je bila za vrijeme Abrahama, pa Izak ode Abimeleku, kralju Filistejaca, u Geraru."},{"v":2,"t":"Jahve mu se ukaza i reče: “Ne silazi u Egipat: boravi u zemlji koju ću ti označiti."},{"v":3,"t":"U ovoj se zemlji nastani, ja ću s tobom biti i blagoslivljati te; tebi i tvome potomstvu dat ću sve ove krajeve, da izvršim zakletvu kojom sam se zakleo tvome ocu Abrahamu."},{"v":4,"t":"Tvoje ću potomstvo umnožiti kao zvijezde na nebesima i tvome ću potomstvu predati sve ove krajeve, tako da će se tvojim potomstvom blagoslivljati svi narodi zemlje;"},{"v":5,"t":"a to zato što je Abraham slušao moj glas i pokoravao se mojim zapovijedima, mojim zakonima i odredbama!”"},{"v":6,"t":"Tako Izak ostane u Geraru."},{"v":7,"t":"Kad su ga mještani pitali o njegovoj ženi, reče: “Ona mi je sestra.” Bojao se reći: “Ona mi je žena”, misleći: “Mještani bi me mogli ubiti zbog Rebeke jer je lijepa.”"},{"v":8,"t":"Kako su se ondje duže zadržali, kralj Filistejaca Abimelek jednom pogleda kroz prozor i opazi kako Izak miluje svoju ženu Rebeku."},{"v":9,"t":"Nato Abimelek pozove Izaka te reče: “Tako, ona ti je žena! Kako si mogao reći da ti je sestra?” Izak mu odgovori: “Jer sam mislio da bih zbog nje mogao poginuti.”"},{"v":10,"t":"Abimelek reče: “Zašto si nam to učinio? Umalo netko od ljudi nije legao s tvojom ženom. Tako bi na nas svalio krivnju.”"},{"v":11,"t":"Onda Abimelek izda naredbu svemu narodu: “Tko se god dotakne ovog čovjeka i njegove žene, glavu će izgubiti.”"},{"v":12,"t":"Izak je sijao u onom kraju i one godine urodilo mu stostruko. Jahve ga blagoslivljao"},{"v":13,"t":"te je čovjek bivao sve bogatiji, dok nije postao vrlo bogat."},{"v":14,"t":"Stekao je stada ovaca i goveda i mnogu služinčad, tako da su mu Filistejci zavidjeli."},{"v":15,"t":"Zato Filistejci zasuše sve bunare što su ih sluge njegova oca bile iskopale - u vrijeme njegova oca Abrahama - i napuniše ih zemljom."},{"v":16,"t":"Onda Abimelek reče Izaku: “Idi od nas jer si postao mnogo moćniji od nas!”"},{"v":17,"t":"Tako Izak ode odande, postavi svoj šator u gerarskoj dolini i nastani se ondje."},{"v":18,"t":"Izak opet iskopa bunare za vodu što su bili iskopani u vrijeme njegova oca Abrahama, a Filistejci ih bili zasuli poslije Abrahamove smrti. On ih je nazvao istim imenima kojima ih je zvao i njegov otac."},{"v":19,"t":"Ali kad su Izakove sluge, dok su u dolini kopale, ondje našle bunar sa živom vodom,"},{"v":20,"t":"pastiri iz Gerara posvade se s Izakovim pastirima govoreći: “Naša je voda!” Bunaru je dao ime Esek, jer su se oni s njim svadili."},{"v":21,"t":"A kad su iskopali drugi bunar te se i zbog njega svađali, nazva ga imenom Sitna."},{"v":22,"t":"Odatle se preseli pa iskopa drugi bunar. Zbog njega se nisu svađali, pa ga nazove imenom Rehobot i protumači: “Jer nam je Jahve dao prostor da se na zemlji umnožimo.”"},{"v":23,"t":"Odande se popne u Beer Šebu."},{"v":24,"t":"Iste mu se noći ukaže Jahve i reče: “Ja sam Bog oca tvoga Abrahama. Ne boj se, ja sam s tobom! Blagoslovit ću te, potomke ti umnožit, zbog Abrahama, sluge svojega.”"},{"v":25,"t":"Izak tu podigne žrtvenik i zazove Jahvu po imenu; postavi ondje svoj šator, a njegove sluge počnu kopati bunar."},{"v":26,"t":"Uto mu dođe Abimelek iz Gerara sa svojim savjetnikom Ahuzatom i s Fikolom, zapovjednikom vojske."},{"v":27,"t":"Izak ih upita: “Zašto ste došli k meni kad me mrzite i kad ste me otjerali od sebe?”"},{"v":28,"t":"Oni odgovore: “Jasno vidimo da je Jahve s tobom. Stoga pomislismo: neka zakletva bude veza između nas i tebe. Daj da s tobom sklopimo savez:"},{"v":29,"t":"ti nama nećeš zla nanositi, kao što mi tebe nismo zlostavljali, nego uvijek prema tebi lijepo postupali i s mirom te otpustili. A blagoslov Jahvin bio nad tobom.”"},{"v":30,"t":"On im priredi gozbu te su jeli i pili."},{"v":31,"t":"Rano ujutro jedni se drugima zakunu. Potom ih Izak otpusti i oni od njega odu u miru."},{"v":32,"t":"Toga istog dana dođu Izakove sluge i obavijeste ga o bunaru što su ga iskopali te mu reknu: “Našli smo vodu.”"},{"v":33,"t":"On ga prozva Šiba. Zato je ime onom gradu do danas - Beer Šeba."},{"v":34,"t":"Kad je Ezavu bilo četrdeset godina, uzme za ženu Juditu, kćer Hetita Beerija, i Basematu, kćer Hetita Elona."},{"v":35,"t":"One postadoše izvor ogorčenja Izaku i Rebeki."}]},"27":{"hr":[{"v":1,"t":"Ostarje Izak, vid mu se očinji gasio. Zato zovne svoga starijeg sina Ezava i reče mu: “Sine!” On mu odgovori: “Evo me!”"},{"v":2,"t":"A on nastavi: “Vidiš, ostario sam, a ne znam dana svoje smrti."},{"v":3,"t":"Zato uzmi svoju opremu, svoj tobolac i luk, pa idi u pustaru i ulovi mi divljači."},{"v":4,"t":"Onda mi pripremi ukusan obrok, kako volim, te mi ga donesi da blagujem, pa da te mognem blagosloviti prije nego umrem.”"},{"v":5,"t":"Rebeka je slušala dok je Izak govorio svome sinu Ezavu, i kad je Ezav otišao u pustaru da ulovi divljači svome ocu,"},{"v":6,"t":"Rebeka reče svome sinu Jakovu: “Upravo sam čula kako tvoj otac govori tvome bratu Ezavu:"},{"v":7,"t":"'Donesi mi divljači te mi priredi ukusan obrok da blagujem pa da te pred licem Jahvinim blagoslovim prije nego umrem.'"},{"v":8,"t":"A sad, sine moj, poslušaj me i učini kako ti naredim."},{"v":9,"t":"Otiđi k stadu i odande mi donesi dva lijepa kozleta, a ja ću od njih prirediti ukusan obrok tvome ocu, kako on voli."},{"v":10,"t":"Onda ti donesi svome ocu da jede te tebe mogne blagosloviti prije nego umre.”"},{"v":11,"t":"Ali Jakov odgovori svojoj majci Rebeki: “E, ali moj je brat Ezav runjav, a ja sam bez dlaka!"},{"v":12,"t":"Možda me se moj otac dotakne te ću u njegovim očima ispasti varalicom i na se svaliti prokletstvo, a ne blagoslov.”"},{"v":13,"t":"Ali njegova mu majka odgovori: “Sine moj, tvoje prokletstvo neka padne na mene! Samo ti mene poslušaj, otiđi i donesi!”"},{"v":14,"t":"Ode on, nađe i donese svojoj majci, a njegova majka priredi ukusan obrok, kako je njegov otac volio."},{"v":15,"t":"Potom Rebeka uzme najljepše odijelo svoga starijeg sina Ezava što je u kući imala, pa u nj odjene svoga mlađeg sina Jakova."},{"v":16,"t":"U kožu kozleta zamota mu ruke i goli dio vrata."},{"v":17,"t":"Stavi zatim ukusan obrok i kruh što ga je pripravila na ruke svoga sina Jakova."},{"v":18,"t":"Ode on k ocu i reče: “Oče!” On odgovori: “Evo me. Koji si ti moj sin?”"},{"v":19,"t":"A Jakov odgovori svome ocu: “Ja sam Ezav, tvoj prvorođenac; učinio sam kako si mi rekao. Sad ustaj, sjedi pa jedi moje lovine, da me onda mogneš blagosloviti.”"},{"v":20,"t":"Izak upita svoga sina: “Kako si tako brzo uspio, sine moj?” On odgovori: “Jer mi je Jahve, Bog tvoj, bio milostiv.”"},{"v":21,"t":"Potom Izak reče Jakovu: “Primakni se, sine moj, da opipam jesi li ti zbilja moj sin Ezav ili nisi.”"},{"v":22,"t":"Jakov se primakne k svome ocu Izaku, koji ga opipa i reče: “Glas je Jakovljev, ali su ruke Ezavove.”"},{"v":23,"t":"Nije ga prepoznao jer su mu ruke bile runjave kao i ruke njegova brata Ezava. Kad ga je htio blagosloviti,"},{"v":24,"t":"upita još jednom: “Jesi li ti zaista moj sin Ezav?” Odgovori on: “Jesam.”"},{"v":25,"t":"Potom reče Izak: “Stavi preda me da blagujem lovine svoga sina pa da te blagoslovi duša moja.” Jakov ga posluži pa je jeo. Zatim mu donese i vina, pa je pio."},{"v":26,"t":"Poslije toga reče mu njegov otac Izak: “Primakni se, sine moj, i poljubi me!”"},{"v":27,"t":"Kad se primače i poljubi ga, Izak osjeti miris njegove odjeće pa ga blagoslovi: “Gle, miris sina mog nalik je mirisu polja koje Jahve blagoslovi."},{"v":28,"t":"Neka ti Bog daje rosu s neba i rodnost zemlje: izobilje žita i mladoga vina."},{"v":29,"t":"Narodi ti služili, plemena ti se klanjala! Braćom svojom gospodari, nek sinci majke tvoje pred tobom padaju! Proklet bio tko tebe proklinje; blagoslovljen tko te blagoslivlje!”"},{"v":30,"t":"Tek što se Jakov udaljio od svoga oca Izaka - pošto je Izak podijelio blagoslov Jakovu - njegov brat Ezav dođe iz lova."},{"v":31,"t":"I on priredi ukusan obrok i donese ga svome ocu. I reče svome ocu: “Ustani, oče moj, i blaguj od lovine svoga sina da me onda mogneš blagosloviti!”"},{"v":32,"t":"A njegov ga otac Izak zapita: “Tko si ti?” On odgovori: “Ja sam tvoj prvorođenac Ezav!”"},{"v":33,"t":"Izak se silno prepadne: “Pa tko je onda bio onaj što je divljači ulovio i meni već donio? Blagovao sam je prije nego si ti došao; onoga sam blagoslovio i blagoslovljen će ostati.”"},{"v":34,"t":"Kad je Ezav čuo riječi svoga oca, kriknu glasno i gorko zaplaka pa reče svome ocu: “I mene blagoslovi, oče!”"},{"v":35,"t":"A on odvrati: “Brat tvoj dođe na prijevaru i odnese tvoj blagoslov.”"},{"v":36,"t":"“Zato valjda što mu je ime Jakov, dvaput me već prevario”, reče Ezav. “Oduzeo mi prvorodstvo, a sad mi evo oduze i blagoslov.” Onda doda: “Zar za me nisi sačuvao nikakva blagoslova?”"},{"v":37,"t":"Izak odgovori Ezavu: “Njega sam već postavio za tvoga gospodara; njemu sam svu njegovu braću predao za sluge; žitom sam ga i vinom opskrbio. A što sad za te mogu učiniti, sine moj?”"},{"v":38,"t":"Ezav odgovori svome ocu: “Zar ti, oče, raspolažeš samo jednim blagoslovom? Blagoslovi i mene, oče moj!” Ezav jecaše na sav glas."},{"v":39,"t":"Tada otac njegov Izak progovori i reče: “Daleko od plodna tla dom tvoj će biti, daleko od rose s neba."},{"v":40,"t":"Od mača svoga ćeš živjeti, brata svoga ćeš služiti. Ali jednom, kada se pobuniš, jaram ćeš njegov stresti sa svog vrata.”"},{"v":41,"t":"Ezav zamrzi Jakova zbog blagoslova kojim ga je otac njegov blagoslovio pa reče u sebi: “Čim dođu dani žalosti za mojim ocem, ubit ću ja svoga brata Jakova.”"},{"v":42,"t":"Kada su Rebeki javili te riječi što ih je izrekao njezin stariji sin Ezav, zovne ona svoga mlađeg sina Jakova te mu reče: “Pazi! Brat ti se Ezav nosi mišlju kako će te ubiti."},{"v":43,"t":"Ali ti, sine moj, poslušaj mene: odmah bježi mome bratu Labanu u Haran."},{"v":44,"t":"Ostani kod njega neko vrijeme, dok bijes brata tvoga na te jenja,"},{"v":45,"t":"dok se srdžba brata tvoga odvrati od tebe te on zaboravi što si mu učinio. Ja ću onda po te poslati i odande te dovesti. Zašto da vas obojicu izgubim u jedan dan!”"},{"v":46,"t":"Potom Rebeka reče Izaku: “Moj mi je život dosadio zbog ovih žena Hetitkinja. Ako se i Jakov oženi kojom kao što su ove urođenice, Hetitkinjom, što će mi onda život!”"}]},"28":{"hr":[{"v":1,"t":"Stoga Izak pozove Jakova, blagoslovi ga te mu naloži: “Nemoj uzimati ženu od kanaanskih djevojaka."},{"v":2,"t":"Odmah se zaputi u Padan Aram, u dom Betuela, oca svoje majke, pa odande sebi uzmi ženu, od kćeri Labana, brata svoje majke."},{"v":3,"t":"A Bog Svemožni, El-Šadaj, neka te blagoslovi i neka te učini rodnim i brojnim, tako da postaneš mnoštvo naroda."},{"v":4,"t":"Neka protegne na te blagoslov Abrahamov, na te i na tvoje potomstvo, tako da zaposjedneš zemlju u kojoj boraviš kao pridošlica, a koju je Bog predao Abrahamu!”"},{"v":5,"t":"Tako Izak otpremi Jakova, i on ode u Padan Aram Labanu, sinu Aramejca Betuela, bratu Rebeke, majke Jakova i Ezava."},{"v":6,"t":"Kad je Ezav vidio kako je Izak blagoslovio Jakova kad ga je otpremao u Padan Aram da odande sebi uzme ženu, naređujući mu kad ga je blagoslivljao: “Ne smiješ uzeti ženu od kanaanskih djevojaka”,"},{"v":7,"t":"i da je Jakov poslušao svoga oca i svoju majku te otišao u Padan Aram,"},{"v":8,"t":"Ezav shvati koliko su djevojke kanaanske mrske njegovu ocu Izaku."},{"v":9,"t":"Stoga ode k Jišmaelu te se, uza žene koje već imaše, oženi Mahalatom, kćerju Jišmaela, sina Abrahamova, a sestrom Nebajotovom."},{"v":10,"t":"Jakov ostavi Beer Šebu i zaputi se u Haran."},{"v":11,"t":"Stigne u neko mjesto i tu prenoći, jer sunce bijaše već zašlo. Uzme jedan kamen s onog mjesta, stavi ga pod glavu i na tom mjestu legne."},{"v":12,"t":"I usne san: ljestve stoje na zemlji, a vrhom do neba dopiru, i anđeli Božji po njima se penju i silaze."},{"v":13,"t":"Uza nj je Jahve te mu govori: “Ja sam Jahve, Bog tvoga praoca Abrahama i Bog Izakov. Zemlju na kojoj ležiš dat ću tebi i tvome potomstvu."},{"v":14,"t":"Tvojih će potomaka biti kao i praha na zemlji; raširit ćete se na zapad, istok, sjever i jug; tobom će se i tvojim potomstvom blagoslivljati svi narodi zemlje."},{"v":15,"t":"Dobro znaj: ja sam s tobom; čuvat ću te kamo god pođeš te ću te dovesti natrag u ovu zemlju; i neću te ostaviti dok ne izvršim što sam ti obećao.”"},{"v":16,"t":"Jakov se probudi od sna te reče: “Zaista se Jahve nalazi na ovome mjestu, ali ja nisam znao!”"},{"v":17,"t":"Potresen, uzviknu: “Kako je strašno ovo mjesto! Zaista, ovo je kuća Božja, ovo su vrata nebeska!”"},{"v":18,"t":"Rano ujutro Jakov uzme onaj kamen što ga bijaše stavio pod glavu, uspravi ga kao stup i po vrhu mu izlije ulja."},{"v":19,"t":"Ono mjesto on nazva Betel, dok je ime tome gradu prije bilo Luz."},{"v":20,"t":"Tada učini zavjet: “Ako Bog ostane sa mnom i uščuva me na ovom putu kojim idem, dade mi kruha da jedem i odijela da se oblačim,"},{"v":21,"t":"te se zdravo vratim kući svoga oca, Jahve će biti moj Bog."},{"v":22,"t":"A ovaj kamen koji sam uspravio kao stup bit će kuća Božja. A od svega što mi budeš davao za te ću odlagati desetinu.”"}]},"29":{"hr":[{"v":1,"t":"Jakov nastavi put i dođe u zemlju istočnu."},{"v":2,"t":"Najednom opazi studenac u polju. Tri su stada ovaca oko njega plandovala, jer se na tome studencu napajahu. Velik se kamen nalazio studencu na otvoru."},{"v":3,"t":"Jedino kad bi se svi pastiri ondje skupili, mogli bi odvaliti kamen s otvora i ovce napojiti; tada bi opet prevalili kamen na njegovo mjesto, na otvor studenca."},{"v":4,"t":"“Odakle ste, braćo moja?” - zapita ih Jakov. “Iz Harana”, odgovore."},{"v":5,"t":"“Poznajete li”, pitaše ih dalje, “Nahorova sina Labana?” “Poznajemo”, odgovore."},{"v":6,"t":"“Je li zdravo?” - opet ih upita. “Zdravo je; a evo mu dolazi kći Rahela sa stadom”, odgovore."},{"v":7,"t":"“Još ima mnogo dana”, nastavi on, “nije vrijeme spraćati blago. Zašto ga ne napojite i ne otjerate na pašu?”"},{"v":8,"t":"“Ne možemo dok se ne skupe svi pastiri”, odgovoriše, “da odvale kamen s otvora studenca, tako da mognemo napojiti ovce.”"},{"v":9,"t":"Dok je on još s njima govorio, dođe Rahela s ovcama svoga oca. Bila je, naime, pastirica."},{"v":10,"t":"Kako Jakov ugleda Rahelu, kćer Labana, brata svoje majke, sa stadom svoga ujaka Labana, Jakov se primače i odvali kamen s otvora studenca te napoji stado svoga ujaka Labana."},{"v":11,"t":"Zatim Jakov poljubi Rahelu, a onda briznu u plač."},{"v":12,"t":"Potom Jakov kaza Raheli da je on sestrić njezina oca, sin Rebekin. Nato ona otrča i obavijesti oca."},{"v":13,"t":"Kad je Laban čuo vijest o Jakovu, sinu svoje sestre, potrča mu u susret. Zagrli ga i poljubi te dovede u svoju kuću. Ispriča Labanu sve što mu se dogodilo."},{"v":14,"t":"A onda Laban reče. “Zbilja si ti moja kost i moje meso!” Pošto je Jakov proboravio s Labanom mjesec dana,"},{"v":15,"t":"Laban reče Jakovu: “Zar ćeš me zato što si mi sestrić badava služiti! Kaži mi koliko ćeš tražiti za najam?”"},{"v":16,"t":"A Laban imaše dvije kćeri. Starijoj bijaše ime Lea, a mlađoj Rahela."},{"v":17,"t":"Lea imala slabe oči, a Rahela bila stasita i lijepa."},{"v":18,"t":"Kako je Jakov volio Rahelu, reče: “Služit ću ti sedam godina za tvoju mlađu kćer Rahelu.”"},{"v":19,"t":"Laban odvrati: “Bolje je da je tebi dam nego kakvu strancu. Ostani sa mnom!”"},{"v":20,"t":"Tako je Jakov služio za Rahelu sedam godina, ali mu se učinile, zbog ljubavi prema njoj, kao nekoliko dana."},{"v":21,"t":"Poslije toga Jakov reče Labanu: “Daj mi moju ženu, jer se moje vrijeme navršilo pa bih htio k njoj.”"},{"v":22,"t":"Laban sabra sav svijet onog mjesta i priredi gozbu."},{"v":23,"t":"Ali navečer uzme svoju kćer Leu pa nju uvede k Jakovu, i on priđe k njoj."},{"v":24,"t":"Laban dade svoju sluškinju Zilpu svojoj kćeri Lei za sluškinju."},{"v":25,"t":"Kad bi ujutro, a to, gle, Lea! Tada Jakov reče Labanu: “Zašto si mi to učinio! Zar te ja nisam služio za Rahelu? Zašto si me prevario?”"},{"v":26,"t":"Laban odgovori: “U našem mjestu nije običaj da se mlađa udaje prije starije."},{"v":27,"t":"Završi s njom ovu ženidbenu sedmicu, a onda ću ti dati i drugu, za drugih sedam godina službe kod mene.” Jakov pristane: navrši onu ženidbenu sedmicu."},{"v":28,"t":"Onda mu Laban dade i svoju kćer Rahelu za ženu."},{"v":29,"t":"Laban dade svoju sluškinju Bilhu svojoj kćeri Raheli za sluškinju."},{"v":30,"t":"Jakov nato priđe Raheli. Rahelu je više volio nego Leu. I tako je služio Labana još sedam godina."},{"v":31,"t":"Jahve je vidio da Lea nije voljena, te je učini plodnom, dok Rahela ostade nerotkinja."},{"v":32,"t":"Lea zače i rodi sina; nadjenu mu ime Ruben, a to znači, kako je ona protumačila: “Jahve je vidio moju nevolju i stoga će me sada muž moj ljubiti.”"},{"v":33,"t":"Opet zače i rodi sina te izjavi: “Jahve je čuo da nisam voljena, stoga mi je dao i ovoga.” Zato mu nadjenu ime Šimun."},{"v":34,"t":"Opet zače i rodi sina te izjavi: “Sad će se moj muž meni prikloniti: tri sam mu sina rodila.” Zato mu nadjenu ime Levi."},{"v":35,"t":"A kad je još jednom začela i sina rodila, izjavi: “Ovaj put hvalit ću Jahvu.” Stoga sinu nadjenu ime Juda. Potom prestade rađati."}]},"30":{"hr":[{"v":1,"t":"Vidjevši Rahela da Jakovu ne rađa djece, postade zavidna svojoj sestri pa reče Jakovu: “Daj mi djecu! Inače ću svisnuti!”"},{"v":2,"t":"Jakov se razljuti na Rahelu te reče. “Zar sam ja namjesto Boga koji ti je uskratio plod utrobe?”"},{"v":3,"t":"A ona odgovori: “Evo moje sluškinje Bilhe: uđi k njoj, pa neka rodi na mojim koljenima, da tako i ja steknem djecu po njoj.”"},{"v":4,"t":"Dade mu dakle svoju sluškinju Bilhu za ženu, i Jakov priđe k njoj."},{"v":5,"t":"Bilha zače te Jakovu rodi sina."},{"v":6,"t":"Tada Rahela reče: “Jahve mi je dosudio pravo. Uslišao je moj glas i dao mi sina.” Stoga mu nadjenu ime Dan."},{"v":7,"t":"Rahelina sluškinja Bilha opet zače i rodi Jakovu drugoga sina."},{"v":8,"t":"Tada Rahela reče: “Žestoko sam se borila sa sestrom, ali sam pobijedila.” Tako mu nadjenu ime Naftali."},{"v":9,"t":"A vidjevši Lea da je prestala rađati, uzme svoju sluškinju Zilpu pa je dade Jakovu za ženu."},{"v":10,"t":"I kad je Leina sluškinja Zilpa rodila Jakovu sina,"},{"v":11,"t":"Lea uskliknu: “Koje sreće!” Tako mu nadjenu ime Gad."},{"v":12,"t":"Leina sluškinja Zilpa rodi Jakovu i drugog sina,"},{"v":13,"t":"i Lea opet uskliknu: “Blago meni! Žene će me zvati blaženom!” Tako mu nadjenu ime Ašer."},{"v":14,"t":"Jednoga dana, u vrijeme pšenične žetve, namjeri se Ruben u polju na ljubavčice te ih donese svojoj majci Lei. I Rahela reče Lei: “Daj mi od ljubavčica svoga sina!”"},{"v":15,"t":"A Lea odgovori: “Zar ti nije dosta što si mi oduzela muža pa još hoćeš da od mene uzmeš i ljubavčice moga sina?” Rahela odgovori: “Pa dobro, neka s tobom noćas leži u zamjenu za ljubavčice tvog sina.”"},{"v":16,"t":"Kad je Jakov navečer stigao iz polja, Lea mu iziđe u susret pa reče: “Treba da dođeš k meni, jer sam te unajmila za ljubavčice moga sina.” One je noći on s njom ležao."},{"v":17,"t":"Bog usliša Leu; ona zače te Jakovu rodi petog sina."},{"v":18,"t":"Onda Lea reče: “Bog mi je uzvratio nagradom što sam ustupila svoju sluškinju svome mužu.” Stoga sinu nadjenu ime Jisakar."},{"v":19,"t":"Lea opet zače i rodi Jakovu šestoga sina."},{"v":20,"t":"Onda Lea reče: “Bog me obdari dragocjenim darom; sada će mi moj muž dati darove: tÓa rodila sam mu šest sinova.” Tako mu nadjenu ime Zebulun."},{"v":21,"t":"Zatim rodi kćer te joj nadjenu ime Dina."},{"v":22,"t":"Uto se Bog sjeti Rahele: Bog je usliša i otvori njezinu utrobu."},{"v":23,"t":"Ona zače i rodi sina te reče: “Ukloni Bog moju sramotu!”"},{"v":24,"t":"Nadjene mu ime Josip, rekavši: “Neka mi Jahve pridoda drugog sina!”"},{"v":25,"t":"Pošto je Rahela rodila Josipa, Jakov reče Labanu: “Pusti me da idem u svoj zavičaj!"},{"v":26,"t":"Daj mi moje žene za koje sam te služio i moju djecu da mogu otići: tÓa dobro znaš kako sam te služio.”"},{"v":27,"t":"A Laban mu odgovori: “Ne idi, ako si mi prijatelj. Znam da me Jahve blagoslivljao zbog tebe.”"},{"v":28,"t":"I nadoda: “Odredi plaću koju želiš od mene, i dat ću ti.”"},{"v":29,"t":"On mu odgovori: “Ti dobro znaš što je moja služba značila za te i kako je tvome blagu bilo sa mnom."},{"v":30,"t":"Malenkost što si je imao prije nego sam ja došao povećala se vrlo mnogo, jer kuda god sam prolazio Jahve te blagoslivljao na mojim koracima. A sad je vrijeme da poradim i za svoj dom.”"},{"v":31,"t":"On upita: “Koliko da ti platim?” Jakov odgovori: “Nemoj mi platiti ništa! Ako mi učiniš ovo, opet ću na pašu goniti i čuvati tvoje stado."},{"v":32,"t":"Daj da prođem danas kroz tvoje stado i od njega izlučim svaku garavu ovcu i svaku šarenu ili napruganu kozu! Neka to bude moja plaća!"},{"v":33,"t":"A ubuduće kad budeš svojim očima provjeravao moju naplatu, moje će poštenje biti svjedok za mene: nađe li se među mojim kozama ijedna koja ne bude šarena ili naprugana, ili među ovcama koja ne bi bila garava, neka se smatra ukradenom!”"},{"v":34,"t":"Laban reče: “Dobro, neka bude kako si kazao.”"},{"v":35,"t":"Ali toga dana Laban izluči naprugane i šarene jarce i sve riđaste i šarene koze - svaku koja je na sebi imala bijelo - i sve garave ovce pa ih preda svojim sinovima."},{"v":36,"t":"I odande gdje je Jakov pasao ostatak Labanova stada udalji se za koja tri dana hoda."},{"v":37,"t":"A Jakov uzme zelenih mladica od topola, badema i platana; na njima izreza bijele pruge, otkrivši bjeliku na mladicama."},{"v":38,"t":"Pruće tako isprugano postavi u korita, u pojila iz kojih se stoka napajala. A kako se stoka parila kad je na vodu dolazila,"},{"v":39,"t":"to su se jarci parili uz pruće, pa su koze kozile prugaste, riđaste i šarene kozliće."},{"v":40,"t":"Tako je i ovce Jakov bio izlučio i glave im okrenuo prema prugastima ili posve garavima što su bile u Labanovu stadu. Tako je za se namicao posebna stada koja nije miješao s Labanovim stadima."},{"v":41,"t":"Osim toga, kad bi se god dobro uzrasla stoka parila, Jakov bi stavio pruće u korita, baš pred oči živine, tako da se pari pred prućem."},{"v":42,"t":"Ali ga pred kržljavu marvu nije stavljao. Tako je kržljava zapadala Labana, a dobro razvijena Jakova."},{"v":43,"t":"Čovjek se tako silno obogatio, stekao mnogu stoku, sluge i sluškinje, deve i magarad."}]},"31":{"hr":[{"v":1,"t":"Uto Jakov dozna kako Labanovi sinovi govore: “Sve dobro našega oca uze Jakov; i od onoga što bi moralo pripasti našem ocu namaknuo je sve ono bogatstvo.”"},{"v":2,"t":"A opazi Jakov i na Labanovu licu da se on ne drži prema njemu kao prije."},{"v":3,"t":"Tada Jahve reče Jakovu: “Vrati se u zemlju svojih otaca, u svoj zavičaj, i ja ću biti s tobom!”"},{"v":4,"t":"Jakov onda pozove Rahelu i Leu u polje, k svome stadu,"},{"v":5,"t":"pa im reče: “Ja vidim na licu vašega oca da se on ne drži prema meni kao prije; ali Bog oca moga sa mnom je bio."},{"v":6,"t":"I same znate da sam vašega oca služio koliko sam god mogao;"},{"v":7,"t":"pa ipak je vaš otac mene varao, deset mi je puta plaću mijenjao. Ali Bog nije dopuštao da mi nanese štetu."},{"v":8,"t":"Ako bi on rekao: 'Svaka šarena neka bude tebi za naplatu', onda bi cijelo stado mladilo šarene; ako bi opet rekao: 'Prugasti neka budu tebi za plaću', onda bi cijelo stado mladilo prugaste."},{"v":9,"t":"Tako je Bog uzimao blago od vašeg oca pa ga meni davao."},{"v":10,"t":"Jednom, kad se stado oplođivalo, nenadano vidjeh u snu da su jarci u stadu, dok su se parili, bili prugasti, mjestimično bijeli i šareni."},{"v":11,"t":"Još u snu anđeo Božji mene zovne: 'Jakove!' 'Evo me!' rekoh."},{"v":12,"t":"A on nastavi: 'Primijeti dobro da su jarci u stadu što se pare prugasti, mjestimično bijeli i šareni. Ja sam, naime, vidio sve što ti je Laban činio."},{"v":13,"t":"Ja sam Bog koji ti se ukazao u Betelu, gdje si uljem pomazao stup i gdje si mi učinio zavjet. Sad ustaj i idi iz ove zemlje; vrati se u svoj zavičaj!'”"},{"v":14,"t":"Nato mu Rahela i Lea odgovore: “Zar još imamo baštinskog dijela u svome očinskom domu?"},{"v":15,"t":"Zar nas otac nije smatrao tuđinkama? TÓa on je nas prodao, a onda je pojeo novac što ga je za nas dobio!"},{"v":16,"t":"Sve bogatstvo što je Bog oduzeo našem ocu zbilja je naše i djece naše. Zato izvrši sve što ti je Bog rekao!”"},{"v":17,"t":"Nato Jakov naprti na deve svoju djecu i svoje žene;"},{"v":18,"t":"pred sobom potjera sve svoje blago, sva svoja dobra što ih je stekao, stoku što ju je namaknuo u Padan Aramu: krenu u zemlju kanaansku, k svome ocu Izaku."},{"v":19,"t":"Laban bijaše otišao da striže svoje ovce, pa Rahela prisvoji kućne kumire koji su pripadali njezinu ocu."},{"v":20,"t":"Jakov zavara Aramejca Labana tako da nije ni slutio da će bježati."},{"v":21,"t":"I pobjegne sa svim što je bilo njegovo. Ubrzo prijeđe Eufrat i upravi put prema brdu Gileadu."},{"v":22,"t":"Trećeg dana obavijeste Labana da je Jakov pobjegao."},{"v":23,"t":"On povede sa sobom svoje rođake te je za Jakovom išao u potjeru sedam dana hoda; stiže ga na brdu Gileadu."},{"v":24,"t":"Ali se Bog ukaza Aramejcu Labanu, noću u snu, te mu reče. “Pazi da protiv Jakova ne poduzimlješ ništa, ni dobro ni zlo!”"},{"v":25,"t":"Uto Laban stigne Jakova. Jakov bijaše postavio svoj šator na Glavici, a Laban se utabori na brdu Gileadu."},{"v":26,"t":"Onda Laban reče Jakovu: “Što si to htio zavaravajući me i odvodeći mi kćeri kao zarobljenice na maču?"},{"v":27,"t":"Zašto si potajno pobjegao, u bludnju me zaveo i nisi me obavijestio? Otpratio bih te s veseljem i pjesmom, uz bubnje i lire."},{"v":28,"t":"Nisi mi dopustio ni da izljubim svoje kćeri i svoju unučad! Zbilja si ludo postupio."},{"v":29,"t":"U mojoj je ruci da s tobom loše postupim. Ali Bog tvoga oca noćas mi reče: 'Pazi da protiv Jakova ne poduzmeš ništa, ni dobro ni zlo!'"},{"v":30,"t":"Sada dobro, otišao si jer si čeznuo za svojim očinskim domom; ali zašto si mi kumire pokrao?”"},{"v":31,"t":"Jakov odgovori Labanu: “Strepio sam od pomisli da bi mi mogao silom oteti svoje kćeri."},{"v":32,"t":"A kumire svoje u koga nađeš, onaj neka pogine! Ovdje pred našom braćom kaži što je tvoga pri meni i nosi!” Jakov nije znao da ih je Rahela prisvojila."},{"v":33,"t":"Tako Laban uđe u šator Jakovljev, pa u šator Lein, onda u šator dviju sluškinja, ali ništa ne nađe. Izišavši iz Leina šatora, uđe u šator Rahelin."},{"v":34,"t":"A Rahela bijaše uzela kumire i stavila ih u sjedalo svoje deve, a onda na njih sjela. Laban je premetao po svemu šatoru, ali ih ne nađe."},{"v":35,"t":"Ona je, naime, rekla svome ocu: “Neka se moj gospodar ne ljuti što ne mogu pred njim ustati jer imam ono što je red kod žena.” I tako je pretraživao, ali kumira nije našao."},{"v":36,"t":"Sad se Jakov ražesti i zađe u prepirku s Labanom. Otvoreno Jakov reče Labanu: “Kakvo je moje zlodjelo, koja li je moja krivnja da me progoniš?"},{"v":37,"t":"Eto si premetnuo sve moje stvari, pa kakav si predmet našao od svega svog kućanstva? Položi ga tu pred moj i svoj rod pa neka oni budu suci među nama dvojicom."},{"v":38,"t":"Za ovih dvadeset godina što sam ih s tobom proveo ni tvoje ovce ni tvoje koze nisu se jalovile niti sam ja jeo ovnova iz tvoga stada."},{"v":39,"t":"Ono što bi zvijer razdrla, tebi nisam donosio, nego bih od svoga gubitak nadoknadio. Ti si to od mene tražio, bilo da je nestalo danju ili da je nestalo noću."},{"v":40,"t":"Često sam danju skapavao od žeđi, a obnoć od studeni. San je bježao od mojih očiju."},{"v":41,"t":"Od ovih dvadeset godina što sam ih proveo u tvojoj kući četrnaest sam ti godina služio za tvoje dvije kćeri, a šest godina za tvoju stoku, jer si mi mijenjao zaradu deset puta."},{"v":42,"t":"Da sa mnom nije bio Bog moga oca, Bog Abrahamov, Strah Izakov, otpravio bi me praznih ruku. Ali je Bog gledao moju nevolju i trud mojih ruku te je sinoć dosudio.”"},{"v":43,"t":"Nato Laban odgovori Jakovu: “Kćeri su moje kćeri; djeca su moja djeca; stada su moja stada, sve što gledaš moje je. Ali što danas mogu učiniti ovim svojim kćerima ili djeci koju su rodile?"},{"v":44,"t":"Pa dobro, hajde da ti i ja napravimo ugovor, tako da bude svjedok između mene i tebe.”"},{"v":45,"t":"Nato Jakov uzme jedan kamen pa ga uspravi kao stup,"},{"v":46,"t":"a onda reče svojim ljudima: “Skupite kamenja!” Tako oni nakupe kamenja i nabace gomilu. Tu su na gomili blagovali."},{"v":47,"t":"Laban je nazva “Jegar sahaduta”, a Jakov je nazva “Gal-ed”."},{"v":48,"t":"Onda Laban izjavi: “Neka ova gomila danas bude svjedok između mene i tebe!” Stoga je nazvana Gal-ed,"},{"v":49,"t":"ali i Mispa, jer je rekao. “Neka Jahve bude na vidu i tebi i meni kad jedan drugog ne budemo gledali."},{"v":50,"t":"Ako budeš loše postupao prema mojim kćerima, ili ako uzmeš druge žene uz moje kćeri, sve da nitko drugi ne bude s nama, znaj da će Bog biti svjedok između mene i tebe.”"},{"v":51,"t":"Potom Laban reče Jakovu: “Ovdje je, evo, gomila; ovdje je stup koji sam uspravio između sebe i tebe:"},{"v":52,"t":"ova gomila i ovaj stup neka budu jamac da ja u zloj namjeri neću ići na te iza ove gomile i da ti nećeš ići na me iza ove gomile i ovog stupa."},{"v":53,"t":"Neka Bog Abrahamov i Bog Nahorov budu naši suci!” Jakov se zakune Bogom - Strahom svoga oca Izaka."},{"v":54,"t":"Poslije toga Jakov prinese žrtvu na Glavici i pozva svoje ljude da blaguju. Poslije objeda proveli su noć na Glavici."}]},"32":{"hr":[{"v":1,"t":"Ranim se jutrom Laban digne, izljubi svoje sinove i svoje kćeri te ih blagoslovi; onda se zaputi natrag u svoje mjesto."},{"v":2,"t":"Jakov je putovao svojim putem, kad mu u susret izađu anđeli Božji."},{"v":3,"t":"Kad ih Jakov opazi, reče: “Ovo je Božje taborište!” Zato nazva ono mjesto Mahanajim."},{"v":4,"t":"Jakov pošalje pred sobom glasnike svome bratu Ezavu u zemlju Seir, u Edomsku pustaru,"},{"v":5,"t":"i naloži im: “Ovako ćete reći mome gospodaru Ezavu: 'Sluga tvoj Jakov poručuje ti: Boravio sam kod Labana i dosad se ondje zadržao."},{"v":6,"t":"Stekao sam goveda, magaradi, ovaca, sluga i sluškinja. Javljam to svome gospodaru, ne bih li našao naklonost u njegovim očima.'”"},{"v":7,"t":"Glasnici se vrate Jakovu te mu reknu: “Bili smo kod tvoga brata Ezava; on sam dolazi ti u susret sa četiri stotine momaka.”"},{"v":8,"t":"Jakov se silno uplaši. U zabrinutosti rastavi na dva tabora ljude, stada, krda i deve što ih je sa sobom imao."},{"v":9,"t":"Računao je: ako Ezav naiđe na jedan tabor i napadne ga, drugi bi se tabor mogao spasiti."},{"v":10,"t":"Onda se Jakov pomoli: “O Bože oca moga Abrahama! Bože oca moga Izaka! O Jahve, koji si mi naredio: 'Vrati se u svoj rodni kraj, i ja ću ti biti dobrostiv!'"},{"v":11,"t":"Nisam vrijedan sve dobrote koju si tako postojano iskazivao svome sluzi. TÓa samo sam sa svojim štapom nekoć prešao ovaj Jordan, a sad sam narastao u dva tabora."},{"v":12,"t":"Izbavi me od šaka moga brata, od šaka Ezavovih! Inače se bojim da bi mogao doći i umlatiti i mene, i majke, i djecu."},{"v":13,"t":"Ti si rekao: 'Obilnim ću te dobrima obasipati i tvoje potomstvo umnožiti poput pijeska u moru koji se ne da prebrojiti zbog množine.'”"},{"v":14,"t":"Ondje provede onu noć; a onda, od onog što je imao pri ruci, pripravi dar svome bratu Ezavu:"},{"v":15,"t":"dvjesta koza i dvadeset jaraca, dvjesta ovaca i dvadeset ovnova;"},{"v":16,"t":"trideset deva dojilica s njihovim mladima; četrdeset krava i deset junaca; dvadeset magarica i deset magaraca."},{"v":17,"t":"Stado po stado preda svojim slugama. Onda reče svojim slugama: “Idite preda mnom, ali držite razmak među stadima!”"},{"v":18,"t":"A prvom izda naredbu rekavši: “Kad te sretne moj brat Ezav pa te upita: 'Čiji si ti? Kamo ideš? Čije je ovo pred tobom?'"},{"v":19,"t":"odgovori: 'Tvoga sluge Jakova; ovo je dar koji šalje svome gospodaru Ezavu; on je tamo za nama.'”"},{"v":20,"t":"Tako je naredio i drugome, pa trećemu i svima drugima koji su išli za stadima: “Ovo i ovako reci Ezavu kad ga sretneš."},{"v":21,"t":"Još mu dodaj: 'A sluga tvoj Jakov i sam je za nama.'” Mislio je naime: “Ako ga unaprijed udobrostivim darovima, a onda se s njim suočim, možda će mi oprostiti.”"},{"v":22,"t":"Tako darovi krenu naprijed, dok je on ostao one noći u taborištu."},{"v":23,"t":"One noći on ustane, uzme svoje obje žene, obje svoje sluškinje i svoje jedanaestero djece te prijeđe Jabok preko gaza."},{"v":24,"t":"Prebacivši njih na drugu stranu toka, prebaci zatim i ostalo što bijaše njegovo."},{"v":25,"t":"Jakov ostane sam. I neki se čovjek rvao s njim dok nije zora svanula."},{"v":26,"t":"Videći da ga ne može svladati, ugane mu bedro pri zglobu, tako da se Jakovu kuk iščašio dok su se rvali."},{"v":27,"t":"Potom reče: “Pusti me jer zora sviće!” Ali on odgovori: “Neću te pustiti dok me ne blagosloviš.”"},{"v":28,"t":"Nato ga onaj zapita: “Kako ti je ime?” Odgovori: “Jakov.”"},{"v":29,"t":"Onaj reče. “Više se nećeš zvati Jakov nego Izrael, jer si se hrabro borio i s Bogom i s ljudima i nadvladao si.”"},{"v":30,"t":"Onda zapita Jakov: “Reci mi svoje ime!” Odgovori onaj: “Za moje me ime ne smiješ pitati!” I tu ga blagoslovi."},{"v":31,"t":"Onom mjestu Jakov nadjene ime Penuel jer - reče - “Vidjeh Boga licem u lice, i na životu ostadoh.”"},{"v":32,"t":"Sunce je nad njim bilo ogranulo kad je prošao Penuel. Hramao je zbog kuka."},{"v":33,"t":"Zato Izraelci do današnjeg dana ne jedu kukovnu tetivu što se nalazi na bedrenom zglobu, budući da je Jakovljev bedreni zglob bio iščašen u kukovnoj tetivi."}]},"33":{"hr":[{"v":1,"t":"Jakov podiže oči i opazi gdje dolazi Ezav i s njime četiri stotine ljudi. Onda on podijeli svoju djecu među Leu, Rahelu i dvije sluškinje;"},{"v":2,"t":"postavi sluškinje i njihovu djecu na čelo; iza njih Leu i njezinu djecu; a Rahelu i Josipa straga."},{"v":3,"t":"Sam prođe naprijed, nakloni se do zemlje sedam puta dok se ne primače svome bratu."},{"v":4,"t":"Ezav mu potrča u susret. Zagrli ga padnuvši mu oko vrata, poljubi ga i zaplaka."},{"v":5,"t":"Onda podiže oči i vidje žene i djecu. “Tko su ovi s tobom?” - zapita. On odgovori: “Djeca kojom je Bog obdario tvoga slugu.”"},{"v":6,"t":"Potom naprijed stupe sluškinje sa svojom djecom te se duboko naklone."},{"v":7,"t":"Naprijed stupi i Lea sa svojom djecom te se duboko nakloni. Najposlije stupe naprijed Josip i Rahela te se duboko naklone."},{"v":8,"t":"Ezav upita: “Što kaniš sa svom ovom povorkom što sam je sreo?” Odgovori: “Naći naklonost svoga gospodara.”"},{"v":9,"t":"Ezav odgovori: “Ja imam dosta, brate moj. Neka ostane tebi što je tvoje.”"},{"v":10,"t":"A Jakov reče: “Nemoj tako! Ako sam našao naklonost u tvojim očima, primi dar iz moje ruke; jer meni je, što si me ljubezno primio, kao da gledam lice Božje."},{"v":11,"t":"Zato prihvati moj dar što sam ti ga donio; Bog mi je bio sklon te imam svega.” Kako ga je uporno nagovarao, Ezav prihvati."},{"v":12,"t":"“Pođimo na put”, reče Ezav, “i ja ću s tobom putovati.”"},{"v":13,"t":"Ali mu on odvrati: “Zna moj gospodar da su djeca nejaka. Osim toga, valja mi se brinuti o ovcama i kravama koje doje: ako bi se tjerale prebrzo samo jednog dana, sve bi pocrkale."},{"v":14,"t":"Neka moj gospodar ide ispred svoga sluge, a ja ću ići polako, uz korak marve pred sobom i uz korak djece, dok ne stignem k svome gospodaru u Seir.”"},{"v":15,"t":"Onda reče Ezav: “Da ti barem ostavim nekoliko ljudi koji se sa mnom nalaze.” Ali on odgovori: “Čemu to? Neka ja samo nađem milost u očima svoga gospodara!”"},{"v":16,"t":"Tako se Ezav onog dana zaputi natrag u Seir,"},{"v":17,"t":"dok je Jakov otišao u Sukot, gdje sebi sagradi kuću, a svom blagu podigne staje. Stoga je onom mjestu dano ime Sukot."},{"v":18,"t":"Došavši tako iz Padan Arama, Jakov sretno stigne u grad Šekem, koji se nalazi u zemlji kanaanskoj, i postavi svoj šator pred gradom."},{"v":19,"t":"A komad zemlje na kojoj je postavio svoj šator kupi od sinova Hamora, Šekemova oca, za stotinu kesita."},{"v":20,"t":"Tu podiže žrtvenik i nazva ga “El, Bog Izraelov”."}]},"34":{"hr":[{"v":1,"t":"Dina, kći koju je Lea rodila Jakovu, iziđe da posjeti neke žene onoga kraja."},{"v":2,"t":"Opazi je Hivijac Šekem, sin Hamora, poglavice kraja, pa je pograbi i na silu s njom leže."},{"v":3,"t":"Njegovo srce prione za Dinu, Jakovljevu kćer, i on se u djevojku zaljubi. Nastojao je pridobiti djevojčino srce."},{"v":4,"t":"Šekem je govorio i svom ocu Hamoru: “Onu mi djevojku uzmi za ženu!”"},{"v":5,"t":"Jakov sazna da je Šekem obeščastio njegovu kćer Dinu. Ali kako su njegovi sinovi bili uz blago na polju, Jakov nije poduzimao ništa dok oni ne dođu."},{"v":6,"t":"Uto dođe k Jakovu Šekemov otac Hamor da se s njim sporazumije,"},{"v":7,"t":"upravo kad su se Jakovljevi sinovi vraćali iz polja. Kad su čuli vijest, ljudi su bili ojađeni i vrlo ljuti. Što je Šekem učinio - legavši s Jakovljevom kćeri - u Izraelu je bila sramota. To se nije smjelo trpjeti."},{"v":8,"t":"Hamor im reče. “Moj se sin Šekem svom dušom zaljubio u vašu kćer. Dajte mu je za ženu!"},{"v":9,"t":"Oprijateljite se s nama: dajite nam svoje kćeri, a naše kćeri uzimajte sebi!"},{"v":10,"t":"Tako možete živjeti među nama; zemlja je pred vama da se naselite, u njoj se slobodno krećete i stječete imovinu!”"},{"v":11,"t":"Potom Šekem reče njezinu ocu i njezinoj braći: “Da nađem milost u vašim očima, dat ću vam što zatražite."},{"v":12,"t":"Tražite od mene koliko hoćete: sve što god zapitate dat ću, samo mi dajte djevojku za ženu.”"},{"v":13,"t":"Jakovljevi sinovi odgovore Šekemu i njegovu ocu Hamoru - govorili su s prijevarom jer je obeščastio njihovu sestru Dinu -"},{"v":14,"t":"te im rekoše: “Ne možemo pristati da svoju sestru damo čovjeku koji nije obrezan, jer bi to za nas bila sramota."},{"v":15,"t":"Jedino ćemo je dati ako postanete kao i mi, ako obrežete sve svoje muškarce."},{"v":16,"t":"Onda vam možemo davati svoje kćeri i uzimati vaše sebi, s vama se naseliti i biti jedan rod."},{"v":17,"t":"A ako ne pristajete na obrezanje, uzet ćemo svoju kćer i otići.”"},{"v":18,"t":"Hamoru i Šekemu, Hamorovu sinu, njihov se zahtjev učini povoljan."},{"v":19,"t":"Mladić nije časio da zahtjev izvrši, jer je čeznuo za Jakovljevom kćeri; a bio je najuvaženiji od svih u očevu domu."},{"v":20,"t":"Tako Hamor i njegov sin Šekem dođu u svoje gradsko vijeće i obrate se svojim sugrađanima ovako:"},{"v":21,"t":"“Ovaj je svijet prijazan; neka se među nama u zemlji nasele; neka se po njoj slobodno kreću; ima dosta prostora u zemlji za njih; možemo uzimati njihove kćeri sebi za žene, a njima davati svoje."},{"v":22,"t":"No ljudi će pristati da među nama žive i s nama budu jedan rod samo ako se svi naši muškarci obrežu kao što su oni obrezani."},{"v":23,"t":"Zar tako ne bi stoka koju su stekli, sve njihovo blago - bilo naše? Pristanimo, pa neka se među nama nasele!”"},{"v":24,"t":"Svi odrasli muškarci koji imaju pravo izaći na gradska vrata poslušaše Hamora i njegova sina Šekema, pa bude obrezan svaki muškarac - svaki koji ima pravo izaći na gradska vrata."},{"v":25,"t":"A trećega dana, dok su oni još bili u bolovima, dva Jakovljeva sina, Šimun i Levi, Dinina braća, pograbe svaki svoj mač i nesmetano dođu u grad te poubijaju sve muškarce."},{"v":26,"t":"Sasijeku mačem Hamora i njegova sina Šekema, uzmu Dinu iz Šekemove kuće i odu."},{"v":27,"t":"Ostali Jakovljevi sinovi dođu na ubijene i opustoše grad što je njihova sestra bila obeščašćena."},{"v":28,"t":"Što je bilo krupne i sitne stoke i magaradi, u gradu i u polju, otjeraju;"},{"v":29,"t":"opljačkaju sva njihova dobra, a svu im djecu i žene - sve što je bilo po kućama - odvedu u roblje."},{"v":30,"t":"Jakov reče Šimunu i Leviju: “Uveli ste me u nepriliku omrazivši me stanovnicima zemlje, Kanaancima i Perižanima. Ako se ujedine protiv mene i napadnu me, dok je nas ovako malo na broj, istrijebit će me s mojim domom.”"},{"v":31,"t":"Oni odgovore: “Zar da prema našoj sestri postupaju kao prema kakvoj bludnici?”"}]},"35":{"hr":[{"v":1,"t":"Bog reče Jakovu: “Ustani, idi gore u Betel te ondje ostani! Načini ondje žrtvenik Bogu koji ti se objavio kad si bježao od svoga brata Ezava!”"},{"v":2,"t":"I Jakov reče svojoj obitelji i svima koji bijahu s njime: “Odbacite tuđe kumire koji se nalaze u vašoj sredini; očistite se i preobucite."},{"v":3,"t":"Idemo gore u Betel; ondje ću načiniti žrtvenik Bogu, koji me uslišao kad sam bio u nevolji i sa mnom bio na putu kojim sam hodio.”"},{"v":4,"t":"Oni predaju Jakovu sve tuđe kumire što su ih imali i naušnice što su bile o njihovim ušima, pa ih Jakov zakopa pod hrast kod Šekema."},{"v":5,"t":"Kad su se zaputili, strah od Boga spopadne okolišna mjesta, tako da nisu išli u potjeru za Jakovljevim sinovima."},{"v":6,"t":"Jakov stigne u Luz, to jest Betel, u zemlji kanaanskoj, i sav puk što je bio s njim."},{"v":7,"t":"Ondje sagradi žrtvenik i mjesto nazva El Betel, jer mu se ondje Bog objavio kad on bježaše pred svojim bratom Ezavom."},{"v":8,"t":"Tada umre Rebekina dojilja Debora te je sahraniše pod Betelom, pod hrastom, koji se otad zove “Tužni hrast”."},{"v":9,"t":"Bog se opet objavi Jakovu kad je stigao iz Padan Arama, te ga blagoslovi."},{"v":10,"t":"Bog mu reče: “Ime ti je Jakov, ali se odsad nećeš zvati Jakov nego će Izrael biti tvoje ime.” Tako ga prozva Izraelom."},{"v":11,"t":"Onda mu Bog reče: “Ja sam El Šadaj - Bog Svesilni! Budi rodan i množi se! Od tebe poteći će narod, mnoštvo naroda, i kraljevi iz tvog će izaći krila."},{"v":12,"t":"Zemlju što je dadoh Abrahamu i Izaku tebi predajem; i potomstvu tvojem poslije tebe zemlju ću ovu dati.”"},{"v":13,"t":"A onda Bog ode od njega gore."},{"v":14,"t":"Na mjestu gdje je Bog s njim govorio Jakov uspravi stup, stup od kamena; na njemu prinese žrtvu i izli ulja."},{"v":15,"t":"A mjesto gdje mu je Bog govorio Jakov nazva Betel."},{"v":16,"t":"Potom odu iz Betela. Još bijaše malo puta do Efrate, a Rahela se nađe pri porođaju. Napali je teški trudovi."},{"v":17,"t":"Kad su joj porođajni bolovi bili najteži, reče joj babica: “Ne boj se jer ti je i ovo sin!”"},{"v":18,"t":"Kad se rastavljala s dušom - jer umiraše Rahela - nadjenu sinu ime Ben Oni; ali ga otac prozva Benjamin."},{"v":19,"t":"Tako umrije Rahela. Sahrane je na putu u Efratu, to jest Betlehem."},{"v":20,"t":"A na njezinu grobu Jakov podigne spomenik - onaj što je na Rahelinu grobu do danas."},{"v":21,"t":"Izrael krenu dalje te razape svoj šator s onu stranu Migdal-Edera."},{"v":22,"t":"Dok je Izrael boravio u onom kraju, ode Ruben i legne s Bilhom, priležnicom svoga oca. Sazna za to Izrael. Izrael je imao dvanaest sinova."},{"v":23,"t":"S Leom: Rubena, koji je Jakovljev prvorođenac, Šimuna, Levija, Judu, Jisakara i Zebuluna;"},{"v":24,"t":"s Rahelom: Josipa i Benjamina;"},{"v":25,"t":"s Bilhom, Rahelinom sluškinjom: Dana i Naftalija;"},{"v":26,"t":"sa Zilpom, sluškinjom Leinom: Gada i Ašera. To su Jakovljevi sinovi što su mu se rodili u Padan Aramu."},{"v":27,"t":"Jakov dođe k svome ocu Izaku u Mamru u Kirjat Arbu, to je Hebron - gdje su boravili Abraham i Izak kao pridošlice."},{"v":28,"t":"Kad je Izaku bilo sto i osamdeset godina, umrije."},{"v":29,"t":"Izak izdahne i umre, starac i godinama zasićen, te bude pridružen svojim precima. Sahrane ga njegovi sinovi, Ezav i Jakov."}]},"36":{"hr":[{"v":1,"t":"Ovo su potomci Ezava, koji se zvao i Edom."},{"v":2,"t":"Ezav je uzeo sebi žene od kanaanskih djevojaka: Adu, kćer Hetita Elona; Oholibamu, kćer Ane, unuku Sibeona Horijca;"},{"v":3,"t":"i Basematu, kćer Jišmaelovu, sestru Nebajotovu."},{"v":4,"t":"Ada Ezavu rodi Elifaza, a Basemata rodi Reuela,"},{"v":5,"t":"Oholibama rodi Jeuša, Jalama i Koraha. To su Ezavovi sinovi koji se rodiše u zemlji kanaanskoj."},{"v":6,"t":"Ezav uzme svoje žene, svoje sinove, svoje kćeri, svu čeljad svoga doma; svoju stoku - krupnu i sitnu; svu imovinu što ju je namakao u zemlji kanaanskoj, pa ode u zemlju seirsku, daleko od svog brata Jakova."},{"v":7,"t":"Njihov se, naime, posjed jako uvećao te nisu mogli ostati zajedno: kraj u kojem su boravili nije ih mogao izdržavati zbog njihova blaga."},{"v":8,"t":"Tako se Ezav - Edom nazvani - naseli u brdskom kraju Seiru."},{"v":9,"t":"Ovo je, dakle, potomstvo Ezava, praoca Edomaca, u brdskom kraju Seiru."},{"v":10,"t":"Ovo su imena Ezavovih sinova: Elifaz, sin Ezavove žene Ade; Reuel, sin Ezavove žene Basemate."},{"v":11,"t":"Elifazovi su sinovi bili: Teman, Omar, Sefo, Gatam i Kenaz."},{"v":12,"t":"Timna je bila inoča Ezavova sina Elifaza; ona je Elifazu rodila Amaleka. To su potomci Ezavove žene Ade."},{"v":13,"t":"A ovo su sinovi Reuelovi: Nahat, Zerah, Šama i Miza. Oni su bili sinovi Ezavove žene Basemate."},{"v":14,"t":"A ovo su opet sinovi Ezavove žene Oholibame, Anine kćeri, unuke Sibeonove; ona je Ezavu rodila Jeuša, Jalama i Koraha."},{"v":15,"t":"Ovo su rodovske glave Ezavovih potomaka. Potomci Ezavova prvorođenca Elifaza: knez Teman, knez Omar, knez Sefo, knez Kenaz,"},{"v":16,"t":"knez Korah, knez Gatam i knez Amalek. To su rodovski glavari Elifazovi u zemlji edomskoj; to su potomci Adini."},{"v":17,"t":"A ovo su potomci Ezavova sina Reuela: knez Nahat, knez Zerah, knez Šama i knez Miza. To su rodovski glavari Reuelovi u zemlji edomskoj; to su potomci Ezavove žene Basemate."},{"v":18,"t":"A ovo su potomci Ezavove žene Oholibame: knez Jeuš, knez Jalam i knez Korah. To su rodovski glavari Ezavove žene Oholibame, kćeri Anine."},{"v":19,"t":"To su bili sinovi Ezava-Edoma, njihovi knezovi."},{"v":20,"t":"A ovo su sinovi Seira Horijca, žitelji one zemlje: Lotan, Šobal, Sibeon, Ana,"},{"v":21,"t":"Dišon, Eser i Dišan. To su koljenovići Horijci, sinovi Seirovi, u zemlji edomskoj."},{"v":22,"t":"Lotanovi sinovi bili su: Hori i Hemam; a sestra Lotanova bila je Timna."},{"v":23,"t":"Ovo su bili sinovi Šobalovi: Alvan, Manahat, Ebal, Šefo i Onam."},{"v":24,"t":"Sinovi Sibeonovi bijahu Aja i Ana. Ana je onaj koji je našao vruća vrela u pustari dok je čuvao magarad svoga oca Sibeona."},{"v":25,"t":"Ovo su bila djeca Ane: sin Dišon i Anina kći Oholibama."},{"v":26,"t":"Ovo su bili sinovi Dišonovi: Hemdan, Ešban, Jitran i Keran."},{"v":27,"t":"Ovo su bili sinovi Eserovi: Bilhan, Zaavan i Akan."},{"v":28,"t":"A sinovi Dišanovi bili su: Uz i Aran."},{"v":29,"t":"Ovo su knezovi Horijaca: knez Lotan, knez Šobal, knez Sibeon, knez Ana,"},{"v":30,"t":"knez Dišon, knez Eser i knez Dišan. To su bili knezovi Horijaca, glavar za glavarom, u zemlji seirskoj."},{"v":31,"t":"Evo kraljeva koji su kraljevali u edomskoj zemlji prije nego je zavladao kralj sinova Izraelovih."},{"v":32,"t":"Beorov sin Bela vladao je u Edomu; njegov se grad zvao Dinhaba."},{"v":33,"t":"Kad je umro Bela, na njegovo se mjesto zakraljio Jobab, sin Zeraha iz Bosre."},{"v":34,"t":"Kad je umro Jobab, zakraljio se na njegovo mjesto Hušam iz temanske zemlje."},{"v":35,"t":"Kad je umro Hušam, zakraljio se na njegovo mjesto Bedadov sin Hadad, koji je potukao Midjance na Moapskom polju. Ime je njegovu gradu bilo Avit."},{"v":36,"t":"Kad je umro Hadad, zakraljio se na njegovo mjesto Samla iz Masreke."},{"v":37,"t":"Kad je umro Samla, zakraljio se na njegovo mjesto Šaul iz Rehobota na Rijeci."},{"v":38,"t":"Kad umrije Šaul, zavlada Baal Hanan, Akborov sin."},{"v":39,"t":"Kad je umro Baal Hanan, Akborov sin, vladaše Hadad. Ime je njegovu gradu bilo Pai. Žena mu se zvala Mehetabela. Bila je kći Matredova, iz Me Zahaba."},{"v":40,"t":"Ovo su imena Ezavovih knezova s njihovim nazivima po rodovima i smještaju: knez Timna, knez Alva, knez Jetet,"},{"v":41,"t":"knez Oholibama, knez Ela, knez Pinon,"},{"v":42,"t":"knez Kenaz, knez Teman, knez Mibzar,"},{"v":43,"t":"knez Magdiel i knez Iram. To su bili knezovi edomski, prema njihovim naseljima u zemlji koju su zaposjeli. To je Ezav, praotac Edomaca."}]},"37":{"hr":[{"v":1,"t":"A Jakov se bijaše nastanio u zemlji gdje je njegov otac boravio kao pridošlica - u zemlji kanaanskoj."},{"v":2,"t":"Evo nasljedstva Jakovljeva. Kao mladić, u dobi od sedamnaest godina, Josip je čuvao stada sa svojom braćom, sinovima Bilhe i Zilpe, koje bijahu žene njegova oca. Josip je ocu svome donosio zle glasove o njima."},{"v":3,"t":"Izrael je volio Josipa više nego ijednog svoga sina jer je bio dijete njegove staračke dobi; i on mu napravi kićenu haljinu."},{"v":4,"t":"Kako njegova braća opaze da ga njihov otac voli više od svih drugih svojih sinova, zamrze ga toliko da mu nisu mogli ni prijaznu riječ progovoriti."},{"v":5,"t":"Jednom Josip usni san i kaza ga svojoj braći, a oni ga zbog toga još više zamrze."},{"v":6,"t":"“Poslušajte”, reče im, “san što sam ga usnio!"},{"v":7,"t":"Pomislite! Vezali smo nasred polja snopove, kadli se najednom moj snop uspravi i stade uzgor. Uto se vaši snopovi okupe okolo i duboko se poklone mom snopu.”"},{"v":8,"t":"Njegova ga braća upitaše: “Kaniš li nad nama zakraljevati? Hoćeš li nam biti gospodar?” I još ga više zamrze zbog njegova pričanja o snovima."},{"v":9,"t":"Usni on još jedan san te ga ispriča svojoj braći: “Još sam jedan san usnuo. Pazite! Sunce, mjesec i jedanaest zvijezda duboko mi se klanjahu!”"},{"v":10,"t":"Kad je to ispričao svome ocu, ukori ga otac i reče mu: “Što znači taj san što si ga usnuo? Zar ćemo doći ja, tvoja majka i tvoja braća pa ti se do zemlje klanjati?”"},{"v":11,"t":"I dok su braća od zavisti bila ljuta na nj, njegov je otac razmišljao o svemu."},{"v":12,"t":"Jednom njegova braća odu čuvati očeva stada blizu Šekema."},{"v":13,"t":"Izrael reče Josipu: “Tvoja braća čuvaju stada kod Šekema, pa hajde da te pošaljem k njima.” On mu odgovori: “Dobro, idem.”"},{"v":14,"t":"Potom će mu otac: “Hajde i vidi kako su ti braća i stoka pa mi javi.” Tako ga otpremi iz doline Hebrona, i on stigne u Šekem."},{"v":15,"t":"Neki čovjek nađe ga gdje luta poljem pa ga upita: “Što tražiš?”"},{"v":16,"t":"“Tražim braću”, odgovori. “Možeš li mi kazati gdje čuvaju stada?”"},{"v":17,"t":"A čovjek reče: “Odavde su otišli. Čuo sam ih gdje govore: 'Hajdemo u Dotan.'” Tako Josip ode za svojom braćom i nađe ih u Dotanu."},{"v":18,"t":"Oni ga opaze izdaleka; prije nego im se približio, počnu se dogovarati da ga ubiju."},{"v":19,"t":"I jedan drugom reče: “Eno stiže onaj sanjar!"},{"v":20,"t":"Hajde da ga sad ubijemo i bacimo u kakvu čatrnju! Možemo kazati da ga je proždrla divlja zvijer. Vidjet ćemo što će biti od njegovih snova!”"},{"v":21,"t":"Ali kad je to čuo Ruben, pokuša da ga izbavi iz njihovih šaka. I reče: “Nemojmo oduzimati njegova života!"},{"v":22,"t":"Ne prolijevajte krvi” - dalje je govorio Ruben. “Bacite ga u čatrnju u pustari; ali ne dižite na nj ruke!” Htio ga je tako izbaviti iz njihovih šaka i odvesti ocu."},{"v":23,"t":"Ali kad je Josip stigao braći, oni s Josipa svuku njegovu haljinu, haljinu kićenu što je bila na njemu;"},{"v":24,"t":"pograbe ga i bace u čatrnju. Čatrnja je bila prazna; nije bilo u njoj vode."},{"v":25,"t":"Potom sjednu da ručaju. Kako podignu svoje oči, opaze povorku Jišmaelaca gdje dolazi iz Gileada. Deve su im nosile mirodije, balzam i mirisavu smolu da ih preprodaju u Egipat."},{"v":26,"t":"Tada reče Juda svojoj braći: “Što ćemo postići ako ubijemo svog brata a krv njegovu sakrijemo?"},{"v":27,"t":"Hajde da ga prodamo Jišmaelcima; ali ne dižimo na nj ruke. TÓa on je naš brat, naše meso.” Braća ga poslušaju."},{"v":28,"t":"Uto naiđu ljudi, midjanski trgovci. Braća izvuku Josipa iz čatrnje i prodaju ga za dvadeset srebrnika Jišmaelcima, a oni Josipa dovedu u Egipat."},{"v":29,"t":"Kad se Ruben vratio k čatrnji i vidio da Josipa nema u čatrnji, razdere svoju odjeću."},{"v":30,"t":"A kad se vratio svojoj braći, povika: “Dječaka nema! Kamo ću ja sad?”"},{"v":31,"t":"A oni uzmu Josipovu haljinu, zakolju jedno kozle i haljinu zamoče u krv."},{"v":32,"t":"Kićenu haljinu otpreme ocu i poruče: “Ovo smo našli; gledaj je li ovo haljina tvoga sina ili nije.”"},{"v":33,"t":"Prepozna je on pa reče: “Haljina je moga sina! Divlja ga je zvijer rastrgla! Na komade je Josip rastrgan!”"},{"v":34,"t":"I razdere Jakov svoje haljine, stavi pokorničku kostrijet oko bokova i dugo vremena oplakivaše svoga sina."},{"v":35,"t":"Svi su ga njegovi sinovi i sve njegove kćeri nastojali utješiti, ali se on ne mogaše utješiti. Govorio je: “Ne, sići ću k svome sinu u Šeol tugujući!” Tako ga je oplakivao njegov otac."},{"v":36,"t":"A Midjanci ga prodaju u Egipat Potifaru, dvoraninu faraonovu, zapovjedniku straže."}]},"38":{"hr":[{"v":1,"t":"Otprilike u to vrijeme Juda ode od svoje braće te okrenu nekom Adulamcu komu ime bijaše Hira."},{"v":2,"t":"Tu Juda zapazi kćer jednog Kanaanca - zvao se Šua - i njome se oženi. Priđe njoj"},{"v":3,"t":"te ona zače i rodi sina, komu dade ime Er."},{"v":4,"t":"Opet ona zače, rodi sina i dade mu ime Onan."},{"v":5,"t":"Još jednog sina rodi te mu nadjene ime Šela. Nalazila se u Kezibu kad je njega rodila."},{"v":6,"t":"Juda oženi svoga prvorođenca Era djevojkom kojoj bijaše ime Tamara."},{"v":7,"t":"Ali Judin prvorođenac Er uvrijedi Jahvu i Jahve ga pogubi."},{"v":8,"t":"Tada reče Juda Onanu: “Priđi k udovici svoga brata, izvrši prema njoj djeversku dužnost i tako očuvaj lozu svome bratu!”"},{"v":9,"t":"Ali Onan, znajući da se sjeme neće računati kao njegovo, ispuštaše ga na zemlju kad god bi prišao bratovoj udovici, tako da ne dade potomstva svome bratu."},{"v":10,"t":"To što je činio uvrijedilo je Jahvu, pa i njega pogubi."},{"v":11,"t":"Onda Juda reče svojoj nevjesti Tamari: “Ostani kao udovica u domu svoga oca dok poodraste moj sin Šela.” Bojao se, naime, da bi i on mogao umrijeti kao i njegova braća. I tako Tamara ode da živi u očevu domu."},{"v":12,"t":"Dugo vremena poslije toga umre Šuina kći, Judina žena. Kad je prošlo vrijeme žalosti, Juda ode, zajedno sa svojim prijateljem Adulamcem Hirom, u Timnu da striže svoje ovce."},{"v":13,"t":"Obavijeste Tamaru: “Eno ti je svekar”, rekoše joj, “na putu u Timnu da striže ovce.”"},{"v":14,"t":"Ona svuče udovičko ruho, navuče koprenu i zamota se pa sjede na ulazu u Enajim, što je na putu k Timni. Vidjela je, naime, da je Šela odrastao, ali nju još ne udaše za nj."},{"v":15,"t":"Kad je Juda opazi, pomisli da je bludnica, jer je bila pokrila lice."},{"v":16,"t":"Svrati se on k njoj i reče: “Daj da ti priđem!” Nije znao da mu je nevjesta. A ona odgovori: “Što ćeš mi dati da uđeš k meni?”"},{"v":17,"t":"“Spremit ću ti jedno kozle od svoga stada”, odgovori. “Treba da ostaviš jamčevinu dok ga ne pošalješ.”"},{"v":18,"t":"A on zapita: “Kakvu jamčevinu da ti ostavim?” Ona odgovori: “Svoj pečatnjak o vrpci i štap što ti je u ruci.” Dade joj jedno i drugo, a onda priđe k njoj i ona po njem zače."},{"v":19,"t":"Potom ona ustade i ode; skide sa sebe koprenu i opet se odjenu u svoje udovičko ruho."},{"v":20,"t":"Uto Juda pošalje kozle po svom prijatelju Adulamcu da iskupi jamčevinu iz ruku žene, ali je nije mogao naći."},{"v":21,"t":"Upita ljude u mjestu: “Gdje je bludnica što se nalazila uz put u Enajim?” Oni mu odgovore: “Ovdje nije nikad bilo bludnice.”"},{"v":22,"t":"Tako se on vrati k Judi pa reče: “Nisam je mogao naći. Osim toga, ljudi mi u mjestu rekoše da ondje nije nikad bilo bludnice.”"},{"v":23,"t":"Onda reče Juda: “Da ne ostanemo za ruglo, neka ih drži! Slao sam joj, eto, ovo kozle, ali je ti nisi našao.”"},{"v":24,"t":"Otprilike poslije tri mjeseca donesoše vijest Judi: “Tvoja nevjesta Tamara odala se bludništvu; čak je u bludničenju i začela.” “Izvedite je”, naredi Juda, “pa neka se spali!”"},{"v":25,"t":"Dok su je izvodili, ona poruči svekru: “Začela sam po čovjeku čije je ovo.” Još doda: “Vidi čiji je ovaj pečatnjak o vrpci i ovaj štap!”"},{"v":26,"t":"Juda ih prepozna pa reče: “Ona je pravednija nego ja, koji joj nisam dao svoga sina Šelu.” Ali više s njom nije imao posla."},{"v":27,"t":"Kad joj je došlo vrijeme da rodi, pokaže se da nosi blizance."},{"v":28,"t":"Dok je rađala, jedan od njih pruži ruku van. Nato babica priveže za njegovu ruku crven konac govoreći: “Ovaj je izišao prvi.”"},{"v":29,"t":"Ali baš tada on uvuče ruku te iziđe njegov brat. A ona reče: “Kakav li proder napravi!” Stoga mu nadjenu ime Peres."},{"v":30,"t":"Poslije iziđe njegov brat koji je oko ruke imao crveni konac. Njemu dadoše ime Zerah."}]},"39":{"hr":[{"v":1,"t":"Josipa dovedoše u Egipat. Tu ga od Jišmaelaca koji su ga onamo doveli kupi Egipćanin Potifar, dvoranin faraonov i zapovjednik njegove tjelesne straže."},{"v":2,"t":"Jahve je bio s Josipom, zato je u svemu imao sreću: Egipćanin ga uzme k sebi u kuću."},{"v":3,"t":"Vidje njegov gospodar da je Jahve s njim i da svemu što mu ruka poduzme Jahve daje uspjeh;"},{"v":4,"t":"zavolje on Josipa, uze ga za dvoranina i postavi ga za upravitelja svoga doma i povjeri mu sav svoj imetak."},{"v":5,"t":"I otkad mu je povjerio upravu svoga doma i svega svog imetka, blagoslovi Jahve dom Egipćaninov zbog Josipa: blagoslov Jahvin bijaše na svemu što je imao - u kući i u polju."},{"v":6,"t":"I tako sve svoje prepusti brizi Josipovoj te se više ni za što nije brinuo, osim za jelo što je jeo. A Josip je bio mladić stasit i naočit."},{"v":7,"t":"Poslije nekog vremena žena njegova gospodara zagleda se u Josipa i reče mu: “Legni sa mnom!”"},{"v":8,"t":"On se oprije i reče ženi svoga gospodara: “Gledaj! Otkako sam ja ovdje, moj se gospodar ne brine ni za što u kući; sve što ima meni je povjerio."},{"v":9,"t":"On u ovoj kući nema više vlasti negoli ja i ništa mi ne krati, osim tebe, jer si njegova žena. Pa kako bih ja mogao učiniti tako veliku opačinu i sagriješiti protiv Boga!”"},{"v":10,"t":"Iako je Josipa salijetala iz dana u dan, on nije pristajao da uz nju legne; nije joj prilazio."},{"v":11,"t":"Jednog dana Josip uđe u kuću na posao. Kako nikog od služinčadi nije bilo u kući,"},{"v":12,"t":"ona ga uhvati za ogrtač i reče: “Legni sa mnom!” Ali on ostavi svoj ogrtač u njezinoj ruci, otrže se i pobježe van."},{"v":13,"t":"Vidjevši ona da je u njezinoj ruci ostavio ogrtač i pobjegao van,"},{"v":14,"t":"zovne svoje sluge te im reče: “Gledajte! Trebalo je da nam dovede jednog Hebrejca da se s nama poigrava. Taj k meni dođe da sa mnom legne, ali sam ja na sav glas zaviknula."},{"v":15,"t":"A čim je čuo kako vičem, ostavi svoj ogrtač pokraj mene i pobježe van.”"},{"v":16,"t":"Uza se je držala njegov ogrtač dok mu je gospodar došao kući."},{"v":17,"t":"Onda i njemu kaza istu priču: “Onaj sluga Hebrejac koga si nam doveo dođe k meni da sa mnom ljubaka!"},{"v":18,"t":"Ali čim je čuo kako vičem, ostavi svoj ogrtač pokraj mene i pobježe van.”"},{"v":19,"t":"Kad je njegov gospodar čuo pripovijest svoje žene koja reče: “Eto, tako sa mnom tvoj sluga”, razgnjevi se."},{"v":20,"t":"Gospodar pograbi Josipa i baci ga u tamnicu - tamo gdje su bili zatvoreni kraljevi utamničenici. I osta u tamnici."},{"v":21,"t":"Ali je Jahve bio s njim, iskaza naklonost Josipu te on nađe milost u očima upravitelja tamnice."},{"v":22,"t":"Tako upravitelj tamnice preda u Josipove ruke sve utamničenike koji su se nalazili u tamnici; i ondje se ništa nije radilo bez njega."},{"v":23,"t":"Budući da je Jahve bio s njim, upravitelj tamnice nije nadgledao ništa što je Josipu bilo povjereno: Jahve bijaše s njim, i što god bi poduzeo, Jahve bi to okrunio uspjehom."}]},"40":{"hr":[{"v":1,"t":"Poslije toga peharnik se i pekar egipatskog kralja ogriješe o svoga gospodara, kralja egipatskog."},{"v":2,"t":"Faraon se razljuti na svoja dva dvoranina, glavnog peharnika i glavnog pekara,"},{"v":3,"t":"te ih stavi u zatvor, u zgradu zapovjednika tjelesne straže - u istu tamnicu gdje je i Josip bio zatvoren."},{"v":4,"t":"Zapovjednik tjelesne straže odredi Josipa da ih poslužuje. Pošto su proveli u zatvoru neko vrijeme,"},{"v":5,"t":"obojica njih - peharnik i pekar egipatskog kralja, utamničenici - usnu san jedne te iste noći. Svaki je usnuo svoj san; i svaki je san imao svoje značenje."},{"v":6,"t":"Kad je Josip ujutro došao k njima, opazi da su neraspoloženi."},{"v":7,"t":"Upita faraonove dvorane koji su bili s njim u zatvoru u zgradi njegova gospodara: “Zašto ste danas tako potišteni?”"},{"v":8,"t":"Odgovore mu: “Sne smo usnuli, ali nikog nema da nam ih protumači.” Josip im reče: “Zar tumačenje ne spada na Boga? Dajte, pričajte mi!”"},{"v":9,"t":"Onda je glavni peharnik ispripovjedio Josipu svoj san: “Sanjao sam da je preda mnom lozov trs."},{"v":10,"t":"Na trsu bile tri mladice. I tek što je propupao, procvjeta i na njegovim grozdovima sazru bobe."},{"v":11,"t":"Kako sam u ruci držao faraonov pehar, uzmem grožđa, istiještim ga u faraonov pehar, a onda stavim pehar u faraonovu ruku.”"},{"v":12,"t":"Josip mu reče: “Ovo ti je značenje: tri mladice tri su dana."},{"v":13,"t":"Poslije tri dana faraon će te pomilovati i vratiti na tvoje mjesto; opet ćeš stavljati pehar faraonu u ruku, kao i prije, dok si mu bio peharnik."},{"v":14,"t":"Kada ti bude opet dobro, sjeti se da sam i ja bio s tobom, pa mi učini ovu uslugu: spomeni me faraonu i pokušaj me izvesti iz ove kuće."},{"v":15,"t":"Jer, zbilja, bio sam silom odveden iz zemlje Hebreja; ni ovdje nisam ništa skrivio, a baciše me u tamnicu.”"},{"v":16,"t":"Kad je glavni pekar vidio kako je Josip dao dobro tumačenje, reče mu: “Usnuh da su mi na glavi tri bijele košare."},{"v":17,"t":"U najgornjoj bilo svakovrsna peciva što ga pekar pripravlja faraonu, ali su ptice jele iz košare povrh moje glave.”"},{"v":18,"t":"Josip odgovori: “Ovo je značenje: tri košare tri su dana."},{"v":19,"t":"Poslije tri dana faraon će uzdići tvoju glavu i o drvo te objesiti te će ptice jesti meso s tebe.”"},{"v":20,"t":"I zaista, trećega dana, kad je faraon priredio gozbu za sve svoje službenike - bio mu je rođendan - iz sredine svojih službenika izluči glavnog peharnika i glavnog pekara."},{"v":21,"t":"Vrati glavnog peharnika u peharničku službu te je i dalje stavljao pehar u faraonovu ruku,"},{"v":22,"t":"a glavnog pekara objesi, kako je Josip protumačio."},{"v":23,"t":"Ipak se glavni peharnik nije sjetio Josipa - zaboravio je na nj."}]},"41":{"hr":[{"v":1,"t":"Poslije dvije godine usnu faraon da stoji pokraj Nila."},{"v":2,"t":"Iz Nila iziđe sedam krava, lijepih i debelih; pasle su po šašu."},{"v":3,"t":"Ali odmah poslije njih iz Nila iziđe sedam drugih krava, ružnih i mršavih, te stanu uz one krave na obali Nila."},{"v":4,"t":"Ružne i mršave krave požderu ono sedam lijepih i pretilih, i uto se faraon probudi."},{"v":5,"t":"Opet zaspi te usnu drugi san: sedam punih i jedrih klasova izraste na jednoj stabljici."},{"v":6,"t":"Ali, eto, poslije njih uzraste sedam klasova šturih, istočnjakom opaljenih."},{"v":7,"t":"Šturi klasovi proždru sedam jedrih i punih klasova. I faraon se probudi, i gle: bio je to san."},{"v":8,"t":"Ujutro faraon bijaše uznemiren u duši, pa pozva sve čarobnjake i sve mudrace egipatske: ispriča im faraon svoje sne, ali mu ih nitko nije mogao protumačiti."},{"v":9,"t":"Onda progovori faraonov glavni peharnik: “Moram danas spomenuti jedan svoj propust."},{"v":10,"t":"Jednom, kad se faraon razljutio na svoje službenike, mene i glavnog pekara stavio je u zatvor u zgradi glavnog upravitelja."},{"v":11,"t":"Usnusmo san iste noći, i ja i on, ali je svaki od nas usnuo san drugog značenja."},{"v":12,"t":"Onda je s nama bio neki mladi Hebrej, sluga zapovjednika straže. Ispričasmo njemu svoje sne, a on nam ih protumači: kaza svakom značenje njegova sna."},{"v":13,"t":"Kako nam ih je protumačio, tako nam se i dogodilo: mene vratiše na moje mjesto, a onoga objesiše.”"},{"v":14,"t":"Faraon odmah pošalje po Josipa; izvuku ga brže-bolje iz tamnice; ošišaju mu kosu, obuku novo odijelo i on stupi pred faraona."},{"v":15,"t":"Onda faraon reče Josipu: “Usnuo sam san, a nitko ga ne može protumačiti. Čuo sam o tebi da možeš protumačiti san čim ga čuješ.”"},{"v":16,"t":"“Ništa ja ne mogu”, odgovori Josip faraonu, “nego će Bog dati pravi odgovor faraonu.”"},{"v":17,"t":"Onda je faraon pripovjedao Josipu: “U svom snu stojim na obali Nila."},{"v":18,"t":"I gle! Iz Nila iziđe sedam debelih i lijepih krava. Pasle su po šašu."},{"v":19,"t":"Poslije njih izađe drugih sedam krava. Bile su mršave, vrlo ružne i koštunjave. Još nikad ne vidjeh onako ružnih krava u svoj zemlji egipatskoj!"},{"v":20,"t":"I sedam mršavih i ružnih krava proždru prvih sedam debelih krava."},{"v":21,"t":"Pa iako su ih progutale, nije se vidjelo da im je što u trbuhu: bile su ružne kao i prije. Uto se probudim."},{"v":22,"t":"Zatim sam u snu vidio kako na jednoj stabljici uzraste sedam punih i lijepih klasova."},{"v":23,"t":"Ali poslije njih uzraste sedam klasova zgrčenih, šturih, istočnjakom opaljenih."},{"v":24,"t":"I šturi klasovi proždru sedam jedrih klasova. Kazao sam ovo i vračarima, ali nema nikoga da mi razjasni.”"},{"v":25,"t":"Onda Josip reče faraonu: “Faraonov je san samo jedan: Bog javlja faraonu što kani učiniti."},{"v":26,"t":"Sedam lijepih krava, to je sedam godina; sedam lijepih klasova opet je sedam godina. Tako je samo jedan san."},{"v":27,"t":"Sedam mršavih i ružnih krava poslije njih, a tako i sedam praznih, istočnjakom opaljenih klasova, označuje sedam gladnih godina."},{"v":28,"t":"To je ono što sam već faraonu rekao: Bog objavljuje faraonu što kani učiniti."},{"v":29,"t":"Dolazi, evo, sedam godina velikog obilja svoj zemlji egipatskoj."},{"v":30,"t":"A poslije njih nastat će sedam gladnih godina, kada će se zaboraviti sve obilje u zemlji egipatskoj."},{"v":31,"t":"Kako glad bude harala zemljom, neće se ni znati da je u zemlji bilo obilje - zbog gladi koja će doći - jer će biti vrlo velika."},{"v":32,"t":"A što se faraonov san ponovio, znači da se Bog na to zaista odlučio i da će to uskoro provesti."},{"v":33,"t":"Zato neka faraon izabere sposobna i mudra čovjeka te ga postavi nad zemljom egipatskom."},{"v":34,"t":"Nadalje, neka se faraon pobrine da postavi nadglednika u zemlji koji će kÓupiti petinu sve žetve u zemlji egipatskoj za sedam godina obilja."},{"v":35,"t":"Neka skupljaju od svakog žita za sedam dobrih godina što dolaze; neka s ovlaštenjem faraonovim sabiru žito za hranu i pohranjuju ga po gradovima."},{"v":36,"t":"Neka zalihe služe za hranu u zemlji za sedam godina gladi što će snaći zemlju egipatsku, tako da za gladi zemlja ne propadne.”"},{"v":37,"t":"Svidje se odgovor faraonu i svim njegovim službenicima."},{"v":38,"t":"Zato faraon reče svojim službenicima: “Zar bismo mogli naći drugoga kao što je on, čovjeka koji bi bio tako obdaren duhom Božjim?”"},{"v":39,"t":"A onda faraon reče Josipu: “Otkako je sve to Bog tebi otkrio, nikoga nema sposobna i mudra kao što si ti."},{"v":40,"t":"Ti ćeš biti upravitelj moga dvora: sav će se moj narod pokoravati tvojim naredbama. Jedino prijestoljem ja ću biti veći od tebe."},{"v":41,"t":"Postavljam te, evo,” reče faraon Josipu, “nad svom zemljom egipatskom.”"},{"v":42,"t":"Poslije toga skine faraon sa svoje ruke pečatni prsten i stavi ga Josipu na ruku. Zatim zaodjene Josipa odjećom od najljepše tkanine, a o vrat mu objesi zlatan lanac."},{"v":43,"t":"Vozio se on u kolima kao njegov zamjenik, a pred njim klicahu: “Abrek! Na koljena!” Tako ga postavi nad svu zemlju egipatsku."},{"v":44,"t":"Još faraon reče Josipu: “Premda sam ja faraon, neće nitko dići svoje ruke ni noge bez tvog odobrenja u svoj zemlji egipatskoj.”"},{"v":45,"t":"Faraon nazva Josipa “Safenat Paneah”, a za ženu mu dade Asenatu, kćer Poti-Fere, svećenika u Onu. I Josip postade poznat po zemlji egipatskoj."},{"v":46,"t":"Josipu je bilo trideset godina kad je stupio u službu faraona, kralja egipatskog. A otišavši Josip ispred faraona, putovao je po svoj zemlji egipatskoj."},{"v":47,"t":"Za sedam rodnih godina zemlja je rađala u obilju;"},{"v":48,"t":"on je - u tih sedam godina što ih je egipatska zemlja uživala - kÓupio od različite ljetine i hranu pohranjivao u gradove, smještajući u svakom gradu urod iz okolnih polja."},{"v":49,"t":"Tako Josip nagomila mnogo žita, kao pijeska u moru, pa ga prestade i mjeriti jer mu mjere ne bijaše."},{"v":50,"t":"Dok još ne nasta gladna godina, Josip imade dva sina koje mu rodi Asenata, kći Poti-Fere, svećenika u Onu."},{"v":51,"t":"Prvorođencu Josip nadjenu ime Manaše, “jer Bog je”, reče, “dao te sam zaboravio svoje teškoće i svoj očinski dom.”"},{"v":52,"t":"Drugomu nadjenu ime Efrajim, “jer Bog me”, reče, “učinio rodnim u zemlji moje nevolje.”"},{"v":53,"t":"Sedam godina obilja koje je uživala zemlja egipatska dođe kraju,"},{"v":54,"t":"a primače se sedam gladnih godina, kako je Josip prorekao. U svim zemljama bijaše glad, a u svoj zemlji egipatskoj bijaše kruha."},{"v":55,"t":"A kad je i sva zemlja egipatska osjetila glad, puk zavapi faraonu za kruh; a faraon reče Egipćanima: “Idite k Josipu i što god vam rekne, činite!”"},{"v":56,"t":"Kad se glad proširi po svoj zemlji, Josip rastvori skladišta te je Egipćane opskrbljivao žitom, jer je glad postala žestoka i u zemlji egipatskoj."},{"v":57,"t":"Sav je svijet išao u Egipat k Josipu da kupuje žita, jer je strašna glad vladala po svem svijetu."}]},"42":{"hr":[{"v":1,"t":"Kad je Jakov čuo da u Egiptu ima žita, reče svojim sinovima: “Što tu zurite jedan u drugoga?"},{"v":2,"t":"Čujem da ima žita u Egiptu. Otiđite dolje te nam ga odande nabavite da ostanemo na životu i ne pomremo.”"},{"v":3,"t":"Tako desetero Josipove braće siđe da nabavi žita iz Egipta."},{"v":4,"t":"Benjamina, Josipova pravog brata, Jakov ne posla s ostalima. “Da ga ne bi zadesila kakva nesreća”, govorio je."},{"v":5,"t":"Među onima koji su išli nabavljati žito, jer u zemlji kanaanskoj vladaše glad, bijahu i sinovi Izraelovi."},{"v":6,"t":"Josip je bio namjesnik u zemlji; on je dijelio žito svemu svijetu. Dođu tako i Josipova braća i poklone mu se licem do zemlje."},{"v":7,"t":"Josip prepozna braću čim ih ugleda, ali se prema njima vladao kao stranac i oštro im govorio. Zapita ih: “Odakle dolazite?” Odgovore: “Iz zemlje kanaanske došli smo da kupimo hrane.”"},{"v":8,"t":"Iako je Josip prepoznao svoju braću, oni njega nisu prepoznali."},{"v":9,"t":"Josip se sjeti snova što ih je o njima sanjao. I reče im: “Vi ste uhode! Došli ste da izvidite slaba mjesta ove zemlje.”"},{"v":10,"t":"Oni mu odgovore: “Ne, gospodaru! Tvoje su sluge došle da nabave hrane."},{"v":11,"t":"Svi smo sinovi jednog oca; pošteni smo ljudi; sluge tvoje nikad nisu bile uhode.”"},{"v":12,"t":"On će im opet: “Ne, nego ste došli da izvidite slaba mjesta ove zemlje.”"},{"v":13,"t":"Nato oni uzvrate: “Nas, tvojih slugu, bijaše dvanaestero braće - sinovi jednog oca, u zemlji kanaanskoj; najmlađi je sad s ocem, a jednoga više nema.”"},{"v":14,"t":"No Josip im dobaci: “Onako kako sam vam već rekao: vi ste uhode!"},{"v":15,"t":"Ovako ću vas iskušati: odavde, tako mi faraona, nećete izići ako vaš najmlađi brat ne dođe ovamo!"},{"v":16,"t":"Pošaljite jednoga između sebe da vam dovede brata, a vi ostali u zatvor! Tako ću iskušati vaše riječi i vidjeti je li u vas istina ili nije. Inače, tako mi faraona, vi ste uhode!”"},{"v":17,"t":"Potom ih baci u zatvor na tri dana."},{"v":18,"t":"Treći im dan reče Josip: “Izvršite to, i ostat ćete na životu, jer sam ja čovjek bogobojazan."},{"v":19,"t":"Ako ste pošteni, neka jedan od vas ostane u zatvoru, a vi ostali idite i nosite žito svojim izgladnjelim domovima."},{"v":20,"t":"Poslije toga dovedite mi svoga najmlađeg brata, tako da se obistine vaše riječi te da ne izginete.” Oni pristanu."},{"v":21,"t":"Zatim je jedan drugom govorio : “Jao nama! Stiže nas kazna zbog našega brata; gledali smo njegovu muku dok nas je molio za milost, ali ga nismo uslišali. Stoga nas je ova nevolja snašla.”"},{"v":22,"t":"Ruben im odvrati: “Zar vam nisam govorio: Ne ogrešujte se o mladića! Ali vi niste slušali. Sad se traži račun za njegovu krv.”"},{"v":23,"t":"Nisu znali da ih Josip razumije, jer su se s njim razgovarali preko tumača."},{"v":24,"t":"On se od njih udalji te zaplaka. Opet se vrati i razgovaraše s njima. Onda izdvoji Šimuna između njih i naredi da bude svezan na njihove oči."},{"v":25,"t":"Potom Josip zapovjedi da im vreće napune žitom; da svakome njegov novac metnu u vreću i da im daju poputninu. Tako im učine."},{"v":26,"t":"Tada oni natovare žito na svoje magarce i krenu odande."},{"v":27,"t":"Kad na prenoćištu jedan od njih otvori svoju vreću da nahrani magarca, opazi svoj novac ozgo u vreći."},{"v":28,"t":"“Moj je novac vraćen!” - povika braći. - “Evo ga u mojoj vreći!” Zadrhta srce u njima. Zgledaše se, uplašeni, i rekoše: “Što nam ovo Bog uradi!”"},{"v":29,"t":"Došavši k svome ocu Jakovu u zemlju kanaansku, kazaše mu sve što ih je snašlo."},{"v":30,"t":"“Čovjek koji je gospodar one zemlje”, rekoše, “oštro nam je govorio i optužio nas kao uhode."},{"v":31,"t":"Pošteni smo ljudi, kazasmo mu, i nikad nismo bili uhode."},{"v":32,"t":"Bilo nas je dvanaestero braće, sinovi istog oca, ali jednoga više nema, dok se najmlađi sad nalazi s našim ocem u zemlji kanaanskoj."},{"v":33,"t":"Ali čovjek koji je gospodar one zemlje reče nam: 'Ovim ću doznati da ste pošteni ljudi: ostavite jednoga brata kod mene, a vi ostali uzmite što vam treba za izgladnjele domove, pa idite."},{"v":34,"t":"Onda mi dovedite svoga najmlađeg brata, tako da znam da niste uhode, nego pošteni ljudi. Poslije toga vratit ću vam vašeg brata, i vi ćete se moći slobodno kretati u ovoj zemlji.'”"},{"v":35,"t":"Kako su praznili svoje vreće, svaki nađe u vreći svoju kesu. Opazivši to, zapadoše u strah - i oni i njihov otac."},{"v":36,"t":"“Mene vi ostavljate bez djece!” - reče im njihov otac. - “Josipa je nestalo, Šimuna nema, a sad biste odveli i Benjamina. Sve se to na me svaljuje!”"},{"v":37,"t":"Onda Ruben reče svome ocu: “Ubij moja dva sina ako ti ga ja natrag ne dovedem! Predaj ga u moje ruke, i ja ću ti ga vratiti!”"},{"v":38,"t":"“Moj sin neće s vama!” - uzvrati on. - “Njegov je pravi brat već mrtav, a on je ostao sam. Ako bi ga na putu na koji ćete poći snašla nesreća, u tuzi biste otpravili moju sijedu glavu dolje u Šeol.”"}]},"43":{"hr":[{"v":1,"t":"Strašna glad pritisla zemlju."},{"v":2,"t":"Kad su pojeli hranu koju bijahu donijeli iz Egipta, njihov im otac reče: “Idite opet i nabavite nam malo hrane.”"},{"v":3,"t":"Nato će mu Juda: “Onaj nam je čovjek jasno rekao: 'Ne smijete preda me ako vaš brat ne bude s vama.'"},{"v":4,"t":"Ako si, dakle, voljan s nama poslati našega brata, mi ćemo otići dolje i kupit ćemo ti žita."},{"v":5,"t":"Ali ako njega ne pustiš s nama, onda mi tamo i ne idemo, jer nam je onaj zaprijetio: 'Ne smijete preda me ako vaš brat ne bude s vama.'”"},{"v":6,"t":"“Zašto ste mi”, zapita Izrael, “nanijeli jad rekavši onom čovjeku da imate još jednoga brata?”"},{"v":7,"t":"Oni odgovore: “Čovjek nas je neprestano zapitkivao o nama i o našoj obitelji: 'Je li vam još živ otac? Imate li još kojega brata?' Mi smo mu odgovarali na pitanja. Kako smo mogli znati da će reći : 'Dovedite svoga brata!'”"},{"v":8,"t":"Potom Juda reče svome ocu Izraelu: “Pusti dječaka sa mnom pa da se dignemo i krenemo; tako ćemo preživjeti, a ne pomrijeti, i mi, i ti, i naša djeca."},{"v":9,"t":"Ja za nj jamčim; mene drži odgovornim za nj. Ako ga tebi ne vratim i preda te ga ne dovedem, bit ću ti kriv svega vijeka."},{"v":10,"t":"TÓa da nismo toliko oklijevali, mogli smo se već i dvaput vratiti.”"},{"v":11,"t":"Njihov otac Izrael reče im: “Kad je tako, neka bude, ali učinite ovo: metnite u torbe najbiranijih proizvoda ove zemlje i ponesite na dar onom čovjeku: nešto balzama, nešto meda i mirodija, mirisne smole, pa lješnjaka i badema."},{"v":12,"t":"Sa sobom uzmite dvostruko novaca, jer treba vratiti novac koji ste našli u grlima svojih vreća. Možda je ono bila zabuna."},{"v":13,"t":"Uzmite svoga brata pa se opet zaputite onom čovjeku."},{"v":14,"t":"Neka Bog Svemogući, El Šadaj, potakne onog čovjeka na milosrđe prema nama te vam pusti i drugoga brata i Benjamina. A ja, moram li bez djece ostati, neka ostanem.”"},{"v":15,"t":"Uzmu ljudi darove; uzmu sa sobom dvostruko novaca, povedu Benjamina te siđu u Egipat i stupe pred Josipa."},{"v":16,"t":"Kad Josip ugleda s njima Benjamina, reče upravitelju svoga kućanstva: “Odvedi ljude u kuću, zakolji jedno živinče i pripremi, jer će ovi ljudi blagovati sa mnom o podne!”"},{"v":17,"t":"Čovjek učini kako je Josip rekao i povede ljude u Josipov dom."},{"v":18,"t":"Ljudi se pobojaše kad su bili povedeni u dom Josipov te rekoše: “Zbog novca koji se našao u našim vrećama prvi put vode nas unutra tako da nas napadnu i zajedno s našom magaradi uzmu za robove.”"},{"v":19,"t":"Stoga se primaknu upravitelju Josipova doma te mu, na ulazu u kuću, reknu:"},{"v":20,"t":"“Oprosti, gospodaru! Mi smo i prije jednom dolazili da nabavimo hrane;"},{"v":21,"t":"i kad smo stigli na prenoćište i otvorili svoje vreće, a to novac svakoga od nas ozgo u njegovoj vreći, naš novac, ista svota. Sad smo ga donijeli sa sobom."},{"v":22,"t":"A ponijeli smo i drugog novca da kupimo hrane. Mi ne znamo tko nam je stavio novac u naše vreće.”"},{"v":23,"t":"“Budite mirni”, reče im on. “Ne bojte se! Bog vaš i Bog vašega oca stavio je blago u vaše vreće. Vaš je novac k meni stigao.” Potom im izvede Šimuna."},{"v":24,"t":"Čovjek zatim uvede ljude u Josipovu kuću; dade im vode da operu noge, a njihovoj magaradi baci p§iće."},{"v":25,"t":"Potom priprave oni svoje darove za dolazak Josipov o podne, jer su čuli da će ondje ručati."},{"v":26,"t":"Kad je Josip došao u kuću, dadu mu darove koje su sa sobom donijeli i do zemlje mu se poklone."},{"v":27,"t":"Upita ih on za zdravlje te će dalje: “A je li dobro vaš stari otac o kome ste mi govorili? Je li još dobra zdravlja?”"},{"v":28,"t":"“Sluga tvoj, otac naš, dobro je i još je dobra zdravlja”, odgovore i duboko se naklone iskazujući poštovanje."},{"v":29,"t":"Podigavši svoje oči, Josip opazi svoga brata Benjamina - sina svoje majke - te upita: “Je li ovo vaš najmlađi brat o kome ste mi govorili?” Onda nastavi: “Bog ti bio milostiv, sine moj!”"},{"v":30,"t":"Josip se poslije toga požuri van jer mu se srce uzbudilo zbog brata; bilo mu je da zaplače. Uđe u jednu sobu i tu se isplaka."},{"v":31,"t":"Onda opere lice, ponovo se javi i, svladavajući se, naredi: “Poslužite ručak!”"},{"v":32,"t":"Staviše njemu napose, njima napose, a napose opet Egipćanima koji su s njim jeli. Egipćani ne bi mogli jesti s Hebrejima, jer bi to Egipćanima bilo odvratno."},{"v":33,"t":"I kad posjedaše pred njim, najstariji prema starosti svojoj, a najmlađi prema mladosti svojoj, samo se zgledahu."},{"v":34,"t":"I naređivaše on da jela ispred njega nose njima, a obrok Benjaminov bijaše pet puta veći od svih ostalih. I pili su i gostili se s njim."}]},"44":{"hr":[{"v":1,"t":"Onda Josip naredi upravitelju svoga kućanstva: “Napuni vreće ovih ljudi hranom koliko mogu ponijeti, a novac svakog stavi u grlo njegove vreće."},{"v":2,"t":"A moj pehar - onaj od srebra - stavi u grlo vreće najmlađega, zajedno s njegovim novcem za žito.” On učini kako mu je Josip naredio."},{"v":3,"t":"Kad je svanulo, otpreme ljude i njihove magarce."},{"v":4,"t":"Tek što su izišli iz grada - nisu bili odmakli daleko - kad Josip reče upravitelju svoga kućanstva: “Na noge! Pođi za onim ljudima! Kad ih stigneš, kaži im: 'Zašto uzvraćate zlo za dobro?"},{"v":5,"t":"Zar iz onog pehara ne pije moj gospodar i ne čita iz njega proricanje? Zlo ste učinili!'”"},{"v":6,"t":"Stigavši ih, ponovi im te riječi."},{"v":7,"t":"Oni odgovore: “Zašto nam gospodar govori tako? Daleko bilo od slugu tvojih da učine takvo što!"},{"v":8,"t":"Čak i novac koji smo našli u svojim vrećama donijeli smo ti natrag iz zemlje kanaanske. Kako bismo onda mogli ukrasti srebra ili zlata iz kuće tvoga gospodara!"},{"v":9,"t":"Onaj u koga se od tvojih slugu nađe, neka se usmrti, a mi drugi postat ćemo robovi tvome gospodaru.”"},{"v":10,"t":"“Premda je ono što predlažeš pravo”, preuzme on, “ipak će samo onaj u koga se ukradeno pronađe biti moj rob, a ostali bit ćete slobodni.”"},{"v":11,"t":"Brže spustiše vreće na zemlju i svaki svoju otvori."},{"v":12,"t":"On je pretraživao, počevši s najstarijim i završivši s najmlađim. Pehar se nađe u Benjaminovoj vreći."},{"v":13,"t":"Nato oni razdru svoje haljine; svaki ponovo natovari svoga magarca i vrate se u grad."},{"v":14,"t":"Kad su Juda i njegova braća ponovo stupili u Josipov dom, još je on bio ondje. Bace se preda nj na zemlju."},{"v":15,"t":"Onda im Josip reče: “Kakvo je to djelo što ste ga učinili? Zar ne znate da se čovjek kao što sam ja bavi proricanjem?”"},{"v":16,"t":"Nato Juda odgovori: “Što bismo mogli reći svome gospodaru? Što možemo kazati, čime li se opravdati? Bog je otkrio zlodjelo tvojih slugu. Evo nas za robove svome gospodaru - jednako nas kao i onog u koga se našao pehar.”"},{"v":17,"t":"“Daleko od mene da učinim tako!” - odgovori. “Nego, onaj u koga se našao pehar bit će moj rob, a vi drugi pođite mirno k svome ocu!”"},{"v":18,"t":"Onda mu se Juda primače i reče: “Gospodaru moj, molim te, dopusti sluzi svojem da rekne riječ ušima gospodara svojega i neka se tvoja srdžba ne razlijeva na tvog slugu. TÓa ti si ravan faraonu."},{"v":19,"t":"Pitao je moj gospodar svoje sluge: 'Imate li oca ili još kojega brata?'"},{"v":20,"t":"Svome smo gospodaru odgovorili: 'Imamo stara oca; on još ima jednog sina, rođena u njegovoj staračkoj dobi. Taj je najmlađi. Njegov je pravi brat umro, tako da je on jedini ostao od svoje majke. Njegov ga otac osobito voli.'"},{"v":21,"t":"Potom si rekao svojim slugama: 'Dovedite mi ga ovamo da ga vide moje oči?'"},{"v":22,"t":"A mi smo odgovorili svome gospodaru: 'Dječak ne može ostaviti oca; kad bi ga ostavio, njegov bi otac umro.'"},{"v":23,"t":"Nato si rekao svojim slugama: 'Ako vaš najmlađi brat s vama ne dođe ovamo, više ne smijete preda me.'"},{"v":24,"t":"Kad smo se vratili tvome sluzi, ocu mome, kazali smo mu riječi moga gospodara."},{"v":25,"t":"Naš nam je otac rekao: 'Idite opet i nabavite nam malo hrane!'"},{"v":26,"t":"Odgovorili smo: 'Ne možemo onamo. Samo ako s nama pođe naš najmlađi brat, sići ćemo, jer ne smijemo pred onoga čovjeka ako ne bude s nama naš najmlađi brat.'"},{"v":27,"t":"Tvoj sluga, otac moj, odvrati nam: 'Kako znate, žena mi je rodila dva sina."},{"v":28,"t":"Jedan je nestao, te sam zaključio: sigurno je rastrgan! Odonda ga više nisam vidio."},{"v":29,"t":"Ako i ovoga od mene odvedete pa ga kakva nesreća snađe, moju ćete sijedu glavu s tugom strovaliti dolje u Šeol.'"},{"v":30,"t":"Ako sad dođem k tvome sluzi, ocu svome, a mladić - čiji je život tako povezan s njegovim - ne bude s nama,"},{"v":31,"t":"on će svisnuti kad vidi da dječaka nema s nama; tako će tvoje sluge strovaliti u tuzi sijedu glavu tvoga sluge, oca našega, dolje u Šeol."},{"v":32,"t":"Jer tvoj je sluga zajamčio ocu svome za dječaka, rekavši: 'Ako ti ga ne vratim, bit ću kriv svome ocu svega vijeka.'"},{"v":33,"t":"Zato, molim te, neka tvoj sluga ostane kao rob mome gospodaru, a dječak neka ide natrag s braćom."},{"v":34,"t":"Jer, kako mogu k svome ocu ako dječaka nema sa mnom! Ne bih mogao gledati jad što bi snašao moga oca.”"}]},"45":{"hr":[{"v":1,"t":"Josip se više nije mogo svladavati pred onima koji su ga okruživali pa povika: “Neka svi odstupe!” Tako nitko nije ostao s Josipom kad se očitovao svojoj braći."},{"v":2,"t":"Briznuo je u glasan plač, da su ga i Egipćani mogli čuti. Doznalo se za to i na faraonovu dvoru."},{"v":3,"t":"“Ja sam Josip”, reče Josip svojoj braći. “Otac mi je, dakle, još na životu!” Ali mu braća nisu mogla odgovoriti, toliko se zapanjiše pred njim."},{"v":4,"t":"Onda će opet Josip svojoj braći: “Primaknite se k meni!” Kad su se primakli, nastavi: “Ja sam Josip, vaš brat; onaj koga ste prodali u Egipat."},{"v":5,"t":"Ali se nemojte uznemirivati i prekoravati što ste me ovamo prodali; jer Bog je onaj koji me pred vama poslao da vas održi u životu."},{"v":6,"t":"Dvije su već godine što je glad došla na zemlju, a još pet godina neće biti ni oranja ni žetve u zemlji."},{"v":7,"t":"Zato me Bog poslao pred vama da vam se sačuva ostatak na zemlji te da vam život spasi velikim izbavljenjem."},{"v":8,"t":"Tako niste vi mene poslali ovamo nego Bog; on me postavio faraonu za oca, gospodara nad svim njegovim domom i vladaocem nad svom zemljom egipatskom."},{"v":9,"t":"Žurite se k mome ocu te mu recite: 'Ovo ti poručuje tvoj sin Josip: Bog me postavio gospodarem nad svim Egiptom; siđi k meni bez oklijevanja."},{"v":10,"t":"Nastanit ćeš se u kraju Gošenu. Tako ćeš biti blizu mene: ti, tvoja djeca, tvoja unučad, tvoje ovce i goveda i sve što je tvoje."},{"v":11,"t":"Ondje ću se za te brinuti, jer će glad potrajati još pet godina. Tako nećeš oskudijevati ni ti, ni tvoja obitelj, niti itko tvoj.'"},{"v":12,"t":"Ta svojim očima možete vidjeti, kao što vidi i moj brat Benjamin, da vam to moja usta govore."},{"v":13,"t":"Pripovjedite ocu o mome visokom položaju u Egiptu i sve što ste vidjeli; i brzo mi ovamo oca dovedite!”"},{"v":14,"t":"Potom zagrli brata Benjamina te zaplaka; a plakao je i Benjamin obisnuvši mu oko vrata."},{"v":15,"t":"Izljubi zatim svu svoju braću, u naručju im se rasplaka. Poslije toga njegova braća zađu s njim u razgovor."},{"v":16,"t":"Glas se pročuje u faraonovu dvoru: “Stigla Josipova braća!” Bilo je to drago faraonu i njegovim dvoranima."},{"v":17,"t":"Onda faraon reče Josipu: “Kaži svojoj braći neka učine ovo: 'Natovarite svoje živine i odmah se uputite u zemlju kanaansku."},{"v":18,"t":"Uzmite svoga oca i svoje obitelji i k meni dođite! Ja ću vam dati najbolju zemlju u Egiptu te ćete uživati od obilja ove zemlje.'"},{"v":19,"t":"A naredi i ovo: 'Ovako učinite: Iz zemlje egipatske potjerajte kola za svoju djecu i svoje žene, uzmite oca i dođite."},{"v":20,"t":"Neka vam se oči ne rastužuju za vašim stvarima, jer sve što je u Egiptu najbolje bit će vaše.'”"},{"v":21,"t":"Sinovi Izraelovi tako učine. Po faraonovoj zapovijedi Josip im dade kola i popudbinu."},{"v":22,"t":"Svakom od njih dade nove haljine, a Benjaminu dade tri stotine srebrnika i petore haljine."},{"v":23,"t":"Isto tako pošalje svome ocu: deset magaraca natovarenih najboljim plodovima egipatskim i deset magarica natovarenih žitom, kruhom i namirnicama ocu za put."},{"v":24,"t":"Isprativši svoju braću na put, reče im: “Nemojte se putem svađati!”"},{"v":25,"t":"I tako oni odoše iz Egipta i stigoše u zemlju kanaansku, k svome ocu Jakovu."},{"v":26,"t":"Kad mu rekoše: “Josip je živ i čak vlada nad svom zemljom egipatskom!”, njegovo se srce skameni jer im nije mogao vjerovati."},{"v":27,"t":"Ali kad mu ispripovjediše sve što im je Josip rekao i kad vidje kola što ih je Josip poslao da ga prevezu, duh njihova oca Jakova oživje."},{"v":28,"t":"“Dosta”, reče Izrael. “Sin moj Josip još je živ! Moram poći i vidjeti ga prije nego umrem.”"}]},"46":{"hr":[{"v":1,"t":"Tako Izrael krene na put sa svim što bijaše njegovo i stigne u Beer Šebu te prinese žrtvu Bogu svoga oca Izaka."},{"v":2,"t":"U noćnom viđenju zovne Bog Izraela: “Jakove! Jakove!” On odgovori: “Evo me!”"},{"v":3,"t":"“Ja sam Bog, Bog tvoga oca. Ne boj se sići u Egipat, jer ću ondje od tebe proizvesti velik narod."},{"v":4,"t":"Ja ću sići u Egipat s tobom i sam ću te vratiti ovamo; a Josip će ti svojom rukom oči zaklopiti.”"},{"v":5,"t":"I Jakov krene iz Beer Šebe. Sinovi Izraelovi postave svoga oca Jakova, svoju djecu i svoje žene u kola što ih je faraon poslao da ga prevezu."},{"v":6,"t":"Uzmu sa sobom svoje blago i dobra što ih bijahu stekli u zemlji kanaanskoj te stignu Jakov i sve njegovo potomstvo u Egipat."},{"v":7,"t":"Sa sobom je u Egipat poveo svoje sinove i unuke, svoje kćeri i kćeri svojih sinova, sve svoje potomstvo."},{"v":8,"t":"Ovo su imena Izraelaca - Jakova i njegovih potomaka - koji su stigli u Egipat: Jakovljev prvorođenac Ruben."},{"v":9,"t":"Rubenovi sinovi: Henok, Falu, Hesron i Karmi."},{"v":10,"t":"Sinovi Šimunovi: Jemuel, Jamin, Ohad, Jakin, Sohar i Šaul, sin Kanaanke."},{"v":11,"t":"Sinovi Levijevi: Geršon, Kehat i Merari."},{"v":12,"t":"Sinovi Judini: Er, Onan, Šela, Peres i Zerah. Er i Onan umrli su u zemlji kanaanskoj. Peresovi sinovi bili su Hesron i Hamul."},{"v":13,"t":"Sinovi Jisakarovi: Tola, Fuva, Jašub i Šimron."},{"v":14,"t":"Sinovi Zebulunovi: Sered, Elon i Jahleel."},{"v":15,"t":"To su sinovi koje je Lea imala s Jakovom u Padan Aramu i još kćerka Dina. U svemu je, dakle, imao sinova i kćeri trideset i troje."},{"v":16,"t":"Sinovi Gadovi: Sifjon, Hagi, Šuni, Esbon, Eri, Arodi i Areli."},{"v":17,"t":"Sinovi Ašerovi: Jimna, Jišva, Jišvi, Berija i sestra im Serah. Sinovi Berijini: Heber i Malkiel."},{"v":18,"t":"To su bili potomci Zilpe, koju je Laban darovao svojoj kćeri Lei. Ona je tako rodila Jakovu šesnaest duša."},{"v":19,"t":"Sinovi Jakovljeve žene Rahele: Josip i Benjamin."},{"v":20,"t":"Josipu su se u egipatskoj zemlji rodili Manaše i Efrajim. Rodila mu ih je kći onskog svećenika Poti-Fere."},{"v":21,"t":"Sinovi Benjaminovi: Bela, Beker, Ašbel, Gera, Naaman, Ehi, Roš, Mupim, Hupim i Ard."},{"v":22,"t":"To su bili potomci Rahelini koje je rodila Jakovu - u svemu njih četrnaest."},{"v":23,"t":"Danov je sin Hušim."},{"v":24,"t":"Sinovi Naftalijevi: Jahseel, Guni, Jeser i Šilem."},{"v":25,"t":"To su bili potomci Bilhe, koju je Laban dao svojoj kćeri Raheli. Ona je Jakovu rodila sedam potomaka."},{"v":26,"t":"Tako je sve Jakovljeve čeljadi što je od njega poteklo i u Egipat doselilo - ne uključujući žena Jakovljevih sinova - u svemu šezdeset i šest osoba."},{"v":27,"t":"I k tome dva sina Josipova što su mu se rodila u Egiptu. Prema tome, sve čeljadi Jakovljeva doma što se naseli u Egiptu bijaše sedamdeset duša."},{"v":28,"t":"Izrael posla Judu naprijed k Josipu da se pred njim pojavi u Gošenu. Kad stignu u gošenski kraj,"},{"v":29,"t":"Josip upregne svoja kola i zaputi se u Gošen - u susret svome ocu Izraelu. Stupivši preda nj, pade mu oko vrata i dugo je tako plakao."},{"v":30,"t":"Onda Izrael reče Josipu: “Sada, pošto sam rođenim očima vidio da si još živ, mogu umrijeti.”"},{"v":31,"t":"Zatim Josip reče svojoj braći i očevoj obitelji: “Otići ću i obavijestiti faraona; reći ću mu: 'Moja braća i obitelj moga oca, koji su bili u zemlji kanaanskoj, došli su k meni."},{"v":32,"t":"Oni su ljudi pastiri, uvijek su se bavili stočarstvom; dotjerali su sa sobom svoja stada i sve što im pripada.'"},{"v":33,"t":"Tako, kad vas faraon pozove i zapita: 'Čime se bavite?'"},{"v":34,"t":"odgovorite: 'Ljudi smo, sluge tvoje, koji se od početka do sad bavimo stočarstvom; i mi i naši preci', tako da se možete naseliti u gošenskom kraju. Svi su, naime, pastiri Egipćanima mrski.”"}]},"47":{"hr":[{"v":1,"t":"Ode, dakle, Josip te obavijesti faraona: “Moj otac i moja braća stigoše sa svojim ovcama i govedima i sa svime što imaju iz zemlje kanaanske, i eno ih u gošenskom kraju.”"},{"v":2,"t":"I uzevši petoricu između svoje braće, uvede ih faraonu."},{"v":3,"t":"Onda faraon zapita njegovu braću: “Čime se bavite?” Odgovore faraonu: “Tvoje su sluge stočari, baš kao što su bili naši preci."},{"v":4,"t":"Došli smo da potražimo kratak boravak u ovoj zemlji”, rekoše faraonu, “jer je nestalo paše za stada tvojih slugu, strašna glad pritište kanaansku zemlju. Dopusti da se tvoje sluge nastane u gošenskom kraju.”"},{"v":5,"t":"[5a] Faraon reče Josipu: [6b] “Neka se, dakle, nastane u gošenskom kraju. A ako znaš da među njima ima prikladnih, postavi ih za nadglednike moga osobnog blaga.” [5b] Tako, kad Jakov i njegovi sinovi stigoše u Egipat i kad faraon, kralj egipatski, to ču, reče Josipu: “Budući da su tvoj otac i tvoja braća došli k tebi,"},{"v":6,"t":"[6a] egipatska ti je zemlja na raspolaganju: smjesti svoga oca i svoju braću u najboljem kraju.”"},{"v":7,"t":"Josip onda dovede svoga oca Jakova faraonu. Jakov blagoslovi faraona."},{"v":8,"t":"A faraon upita Jakova: “Koliko ti je godina?”"},{"v":9,"t":"Jakov odgovori faraonu: “Godina moga lutalačkog življenja ima stotina i trideset. Malo ih je i nesretne su bile godine moga života; ne dostižu brojem godine življenja na zemlji mojih otaca.”"},{"v":10,"t":"Poslije toga Jakov se oprosti s faraonom i ode od njega."},{"v":11,"t":"Tako Josip nastani svoga oca i svoju braću davši im u vlasništvo najljepši kraj egipatske zemlje, u kraju Ramsesovu, kako je faraon naredio."},{"v":12,"t":"A Josip opskrbi hranom svoga oca, svoju braću i svu očevu obitelj sve do najmanjega."},{"v":13,"t":"Nigdje nije bilo hrane jer je pritisla strašna glad: izmuči ona i zemlju egipatsku i zemlju kanaansku."},{"v":14,"t":"Josip pobra sav novac što se nalazio u zemlji egipatskoj i zemlji kanaanskoj u zamjenu za žito koje se prodavalo i odnese novac u faraonov dvor."},{"v":15,"t":"Kad je nestalo novca u zemlji egipatskoj i zemlji kanaanskoj, svi Egipćani dođu k Josipu te mu reknu: “Daj nam kruha! Zašto da pomremo pred tvojim očima? Novca više nema.”"},{"v":16,"t":"Josip odgovori: “Predajte svoju stoku pa ću vam dati žita u zamjenu za stoku kad je novca nestalo.”"},{"v":17,"t":"Tako su oni dovodili svoju stoku Josipu, a Josip im davaše kruh u zamjenu za konje, za sitnu i krupnu stoku i za magarad. Tako ih je one godine opskrbljivao kruhom u zamjenu za sve njihovo blago."},{"v":18,"t":"Kad je ona godina prošla, dođu k njemu i druge godine te mu reknu: “Ne možemo sakriti od svoga gospodara: novca je nestalo, blaga su već ustupljena gospodaru; drugo ništa ne preostaje da gospodaru ustupimo nego sebe i svoje oranice."},{"v":19,"t":"Zašto da uništimo na tvoje oči i sebe i svoje zemlje? Uzmi i nas i naše zemlje u zakup za kruh, i tako ćemo zajedno sa svojom zemljom postati faraonovi kmetovi; daj sjemena da preživimo: da ne izginemo i da nam oranice ne postanu pustoš!”"},{"v":20,"t":"Tako Josip steče faraonu u posjed sve egipatske oranice, jer je svaki Egipćanin, kako ih pritisnu glad, prodao svoje njive. Tako je zemlja postala faraonovo vlasništvo,"},{"v":21,"t":"a narod od jednog kraja Egipta do drugoga njegovim robljem."},{"v":22,"t":"Jedino nije preuzeo svećeničkih imanja, jer je faraon davao svećenicima određeni dio, i tako su živjeli od prihoda što im ga je faraon davao. Stoga nisu prodali svojih imanja."},{"v":23,"t":"Onda Josip reče svijetu: “Budući da sam danas za faraona prekupio i vas i vašu zemlju, evo vam sjeme pa zasijte zemlju."},{"v":24,"t":"A kad bude pobiranje ljetine, faraonu ćete davati jednu petinu, dok će četiri petine ostajati vama: za zasijavanje polja, za hranu vama i onima koji su u vašim domovima i za hranu vašoj djeci.”"},{"v":25,"t":"Oni odgovore: “Život si nam spasio! Mi smo zahvalni svome gospodaru što možemo biti faraonovi robovi.”"},{"v":26,"t":"Tako Josip napravi za Egipat zemljišni zakon koji i danas vrijedi: petina pripada faraonu; jedino svećenička imanja nisu prešla faraonu."},{"v":27,"t":"Izraelci se nastaniše u zemlji egipatskoj, u kraju gošenskom; u njem stekoše vlasništvo; bijahu rodni i broj im se veoma umnoži."},{"v":28,"t":"U zemlji egipatskoj poživje Jakov sedamnaest godina. Tako je duljina Jakovljeva života iznosila sto četrdeset i sedam godina."},{"v":29,"t":"A kad se približi vrijeme Izraelu da umre, pozva svoga sina Josipa te mu reče: “Ako mi želiš ugoditi, stavi svoju ruku pod moje stegno kao jamstvo svoje odanosti meni: nemoj me sahraniti u Egiptu!"},{"v":30,"t":"Kad legnem dolje sa svojim ocima, prenesi me iz Egipta gore i sahrani me u njihovu grobnicu!” “Učinit ću kako si rekao”, odgovori."},{"v":31,"t":"“Zakuni mi se!” - reče. I on mu se zakle. Tada se Izrael duboko prignu na uzglavlju."}]},"48":{"hr":[{"v":1,"t":"Poslije nekog vremena jave Josipu: “Eno ti je otac obolio.” Nato on uzme sa sobom svoja dva sina, Manašea i Efrajima."},{"v":2,"t":"Kad Jakovu rekoše: “Evo ti je došao sin Josip”, Izrael skupi svoje snage i sjede na postelju."},{"v":3,"t":"Reče Jakov Josipu: “Bog Svemožni, El Šadaj, objavi mi se u Luzu, u zemlji kanaanskoj; blagoslov mi dade,"},{"v":4,"t":"a potom mi reče: 'Učinit ću te rodnim i mnogobrojnim, učinit ću da postaneš skup naroda, a tvome potomstvu poslije tebe dat ću ovu zemlju u posjed zauvijek.'"},{"v":5,"t":"Sad, oba tvoja sina što su ti se rodila u zemlji egipatskoj, prije nego sam ja stigao k tebi u Egipat, neka budu moji - Efrajim i Manaše neka budu moji kao i Ruben i Šimun!"},{"v":6,"t":"A djeca što su ti se rodila poslije njih neka ostanu tvoja; a u svom nasljedstvu neka se zovu po imenu svoje braće."},{"v":7,"t":"Kad sam se, naime, vraćao iz Padana, na moju žalost, tvoja majka Rahela umrije na putovanju u kanaansku zemlju, tek u maloj udaljenosti od Efrate. Sahranio sam je ondje uz put u Efratu, sadašnji Betlehem.”"},{"v":8,"t":"Opazivši Izrael Josipove sinove, zapita: “Tko su ovi?”"},{"v":9,"t":"Josip odgovori svome ocu: “Sinovi su to moji koje mi je Bog dao ovdje.” “Dovedi mi ih da ih blagoslovim”, reče."},{"v":10,"t":"Izraelu oči oslabile od starosti, nije vidio. Zato mu privede sinove, a on ih poljubi i zagrli."},{"v":11,"t":"Potom Izrael reče Josipu: “Nisam očekivao da ću još ikada vidjeti tvoje lice; kad, evo, Bog mi dade da vidim i tvoje potomke.”"},{"v":12,"t":"Josip ih tada skine s njegovih koljena i duboko se, sve do zemlje, nakloni."},{"v":13,"t":"Nato ih uze Josip obojicu - Efrajima svojom desnicom, Izraelu nalijevo, a Manašea svojom ljevicom, Izraelu nadesno - te ih k njemu primače."},{"v":14,"t":"Ali Izrael ispruži svoju desnicu i stavi je na Efrajimovu glavu, premda je bio mlađi, a svoju ljevicu na glavu Manašeovu - tako je držao ruke unakrst - iako je Manaše bio prvorođenac."},{"v":15,"t":"Tako je davao svoj blagoslov Josipu govoreći: “Bog, čijim su putovima hodili oci moji Abraham i Izak, Bog, koji mi je pastir bio otkako postah pa do danas,"},{"v":16,"t":"anđeo koji me od svakog zla izbavljao - djecu ovu neka blagoslovi! Neka se ime moje i mojih pređa Abrahama i Izaka po njima spominje! U mnoštva se mnogobrojna po zemlji razmnožili!”"},{"v":17,"t":"Kad je Josip vidio da je njegov otac položio desnicu na Efrajimovu glavu, njegovim se očima to učini krivo; zato posegne za rukom svoga oca da je pomakne s Efrajimove glave na glavu Manašeovu."},{"v":18,"t":"“Ne tako, oče moj,” reče Josip svome ocu, “jer ovo je prvorođenac; zato stavi desnicu na njegovu glavu!”"},{"v":19,"t":"Ali njegov otac to odbije rekavši: “Znam ja, sine moj, znam; i od njega će postati narod i bit će velik. Ali njegov mlađi brat bit će veći od njega, a njegovo će potomstvo biti mnoštvo.”"},{"v":20,"t":"Onoga ih, dakle, dana blagoslovi rekavši: “Vama nek' se Izrael blagoslivlja govoreći: Kao što je Efrajimu i Manašeu, nek' i tebi Bog učini!” Tako stavi Efrajima pred Manašea."},{"v":21,"t":"Poslije Izrael reče Josipu: “Ja ću, evo, naskoro umrijeti; no Bog će biti s vama i opet vas dovesti u zemlju vaših otaca."},{"v":22,"t":"A tebi ostavljam Šekem, nešto više nego tvojoj braći, što sam ga svojim mačem i lukom osvojio od Amorejaca.”"}]},"49":{"hr":[{"v":1,"t":"Jakov zatim sazva svoje sinove te reče: “Skupite se da vam kažem što će vas snaći u kasnije vrijeme:"},{"v":2,"t":"Okupite se, čujte, sinovi Jakovljevi, čujte oca svoga Izraela!"},{"v":3,"t":"Ti Rubene, moj prvorođenče, snaga ti si moja, prvenac moje muškosti. Ističeš, se ponosom, snagom se ističeš,"},{"v":4,"t":"no, poput vode nabujao, nećeš više imati prvenstva, jer na ležaj oca svog se pope, moj tad oskvrnu krevet."},{"v":5,"t":"Šimun i Levi braća su prava! Mačevi im oruđe nasilja."},{"v":6,"t":"Na njihova vijećanja ja ne silazio, u njihovim zborovima udjela ne imao! U srdžbi su svojoj ljude ubijali; u obijesti bikove sakatili."},{"v":7,"t":"Prokleta im srdžba, jer je prežestoka! Prokleta im obijest, jer je preokrutna! Razdijelit ću ih po Jakovu, Izraelom raspršiti."},{"v":8,"t":"Judo! Tvoja braća slavit će te; svagda ti je šaka na šiji dušmana, sinci oca tvoga tebi će se klanjat."},{"v":9,"t":"Judo, laviću mali! Plijenom si se, sine, udebljao; poput lava, poput lavice legao potrbuške! Tko bi ga dražiti smio?"},{"v":10,"t":"Od Jude žezlo se kraljevsko, ni palica vladalačka od nogu njegovih udaljiti neće dok ne dođe onaj kome pripada - kome će se narodi pokoriti."},{"v":11,"t":"Svog magarca za lozu privezuje, mlado magarice svoje za čokot. U vinu on kupa svoju odjeću svoju halju u krvi od grožđa."},{"v":12,"t":"Oči su mu od vina mutne, zubi bjelji od mlijeka."},{"v":13,"t":"Zebulun će stanovati uz obalu morsku, luka spasa bit će brodarima, uz bok njegov Sidon će ležati."},{"v":14,"t":"Jisakar je koščat magarac polegao među ogradama."},{"v":15,"t":"Vidje da je odmor ugodan, a zemlja lijepa, te leđa svoja pod teret podmetnu i na tlaku pristade."},{"v":16,"t":"Dan će narod svoj suditi kao svako pleme Izraelovo."},{"v":17,"t":"Nek' Dan zmija bude na putu, guja pokraj staze što će konja za zglob ujesti, i njegov konjik nauznak će pasti."},{"v":18,"t":"U spas tvoj se, Jahve, uzdam!"},{"v":19,"t":"Gada će pljačkat razbojnici, pljačkom će im za petama biti."},{"v":20,"t":"U Ašera bit će hrane, poslastica za kraljeve."},{"v":21,"t":"Naftali je košuta lakonoga koja krasnu lanad mladi."},{"v":22,"t":"Josip je stablo plodno, plodno stablo kraj izvora, grane svoje grana preko zida."},{"v":23,"t":"Strijelci njega saletjeli, strijeljali ga, opljačkali."},{"v":24,"t":"Ali luk mu čvrst ostaje, mišice mu ojačale, rukom Jakog Jakovljeva, imenom Pastira, Stijene Izraela,"},{"v":25,"t":"Bogom, Ocem tvojim, koji ti pomaže, Svesilnim koji te blagoslivlje blagoslovom ozgo sa nebesa, blagoslovom ozdo iz dubina, blagoslovom iz svih prsa, iz svih utroba!"},{"v":26,"t":"Blagoslovom klasja i cvjetova, blagoslovom drevnih brda, želja vječnih brežuljaka - nek' se oni spuste na Josipa, između braće posvećenog!"},{"v":27,"t":"Benjamin je vuk grabežljivi, lovinu on jutrom jede, a navečer plijen dijeli.”"},{"v":28,"t":"Sve su to Izraelova plemena - dvanaest ih na broj - i to im je otac rekao kad ih je blagoslivljao; svakoga je od njih blagoslovio njegovim blagoslovom."},{"v":29,"t":"Poslije toga im dade ovu naredbu: “Naskoro ću se pridružiti svojim precima. Sahranite me kraj mojih otaca,"},{"v":30,"t":"u spilji što se nalazi na polju Efrona, Hetita, u spilji na polju Makpeli, nasuprot Mamri, u zemlji kanaanskoj. To je ona koju je Abraham kupio s poljem od Hetita Efrona za mjesto sahranjivanja."},{"v":31,"t":"Ondje je sahranjen Abraham i njegova žena Sara; sahranjeni su ondje Izak i njegova žena Rebeka; ondje sam ja sahranio Leu."},{"v":32,"t":"Polje i spilja na njemu kupljeni su od Hetita.”"},{"v":33,"t":"Kad je Jakov tako naputio svoje sinove, povuče noge natrag na postelju te izdahnu - pridruži se svojim precima."}]},"50":{"hr":[{"v":1,"t":"Josip se baci na oca, suzama mu oblije lice, izljubi ga."},{"v":2,"t":"Poslije toga Josip naredi liječnicima koji su se nalazili u njegovoj službi da mu oca balzamiraju, i oni balzamiraše Izraela."},{"v":3,"t":"Trebalo je četrdeset dana: toliko, naime, traje balzamiranje. Sedamdeset su ga dana Egipćani oplakivali."},{"v":4,"t":"A kad je prošlo vrijeme oplakivanja, Josip reče onima u dvoru faraonovu: “Učinite mi milost i prenesite faraonu ovo:"},{"v":5,"t":"Moj me otac zakleo govoreći: 'Kad umrem, sahrani me u grob koji sam sebi pripravio u zemlji kanaanskoj!' Dopusti mi da odem gore i sahranim oca, a onda ću se vratiti.”"},{"v":6,"t":"Faraon odgovori: “Otiđi gore i sahrani svoga oca kako si mu se zakleo.”"},{"v":7,"t":"Tako Josip ode da sahrani oca. S njim su pošli i svi faraonovi službenici - odličnici njegova dvora i svi dostojanstvenici egipatske zemlje;"},{"v":8,"t":"sva Josipova obitelj, njegova braća i očeva porodica. Jedino su u gošenskom kraju ostala njihova djeca, njihove ovce i goveda."},{"v":9,"t":"S njim su išla i kola i konjanici: bila je to vrlo duga povorka."},{"v":10,"t":"Stigavši u Goren Haatad, s onu stranu Jordana, održaše ondje veliko i svečano naricanje. Josip održa sedmodnevnu žalost za ocem."},{"v":11,"t":"Kad su stanovnici te zemlje, Kanaanci, vidjeli tugovanje u Goren Haatadu, rekoše: “To ti je svečano naricanje Egipćana!” Zato nazovu to mjesto Abel-Misrajim. Nalazi se s onu stranu Jordana."},{"v":12,"t":"Jakovljevi sinovi učine kako im je naredio otac:"},{"v":13,"t":"odnesu ga u zemlju kanaansku te ga sahrane u spilji na polju Makpeli kod Mamre, polju što ga je Abraham kupio od Hetita Efrona za sahranjivanje."},{"v":14,"t":"Pošto je sahranio svoga oca, Josip se vrati u Egipat - on, njegova braća i svi koji su s njim išli da mu oca pokopaju."},{"v":15,"t":"Kad su Josipova braća vidjela da im je otac umro, rekoše: “Što ako je Josip na nas ljut i pokuša uzvratiti nam za sve zlo koje smo mi njemu nanijeli?”"},{"v":16,"t":"Stoga poruče Josipu ovako: “Pred svoju smrt tvoj je otac naredio:"},{"v":17,"t":"'Ovako recite Josipu: Oprosti braći svojoj zlo i grijeh što su onako okrutno prema tebi postupili.' Oprosti, dakle, uvredu slugama Boga svoga oca!” Na te riječi Josip brizne u plač."},{"v":18,"t":"Tada sama njegova braća dođu k njemu, bace se preda nj te mu reknu: “Evo nas k tebi da budemo tvoji robovi!”"},{"v":19,"t":"Josip im odvrati: “Ne bojte se! TÓa zar sam ja namjesto Boga!"},{"v":20,"t":"Osim toga, iako ste vi namjeravali da meni naudite, Bog je bio ono okrenuo na dobro: da učini što se danas zbiva - da spasi život velikom narodu."},{"v":21,"t":"Zato se ne bojte! Ja ću se brinuti za vas i za vašu djecu.” Tako ih je smirio ljubeznim riječima."},{"v":22,"t":"Josip ostane u Egiptu zajedno s rodom svojim i očevim. Poživje Josip stotinu i deset godina."},{"v":23,"t":"Tako je Josip gledao Efrajimovu djecu do trećeg koljena; a rađala se djeca i Makiru, Manašeovu sinu, na Josipovim koljenima."},{"v":24,"t":"Napokon reče Josip svojoj braći: “Ja ću, evo, naskoro umrijeti. Ali će se Bog, zacijelo, sjetiti vas i odvesti vas iz ove zemlje u zemlju što ju je pod zakletvom obećao Abrahamu, Izaku i Jakovu.”"},{"v":25,"t":"Tada Josip zakune Izraelove sinove: “Bog će se vas doista sjetiti, i tada ponesite moje kosti odavde!”"},{"v":26,"t":"Josip umrije kad mu bijaše sto i deset godina; balzamiraše ga i u Egiptu položiše u lijes."}]}},"EXO":{"1":{"hr":[{"v":1,"t":"Ovo su imena Izraelovih sinova koji su s Jakovom sišli u Egipat, svaki sa svojim domom:"},{"v":2,"t":"Ruben, Šimun, Levi i Juda;"},{"v":3,"t":"Jisakar, Zebulun i Benjamin;"},{"v":4,"t":"Dan i Naftali; Gad i Ašer."},{"v":5,"t":"U svemu Jakovljevih potomaka bijaše sedamdeset duša. A Josip je već bio u Egiptu."},{"v":6,"t":"I umre Josip, a pomru i sva njegova braća i sav onaj naraštaj."},{"v":7,"t":"Ali su Izraelci bili rodni, namnožili se i silno ojačali, tako da su napučili zemlju."},{"v":8,"t":"Uto u Egiptu zavlada novi kralj koji nije poznavao Josipa."},{"v":9,"t":"I reče on svome puku: “Eto, sinovi su Izraelovi postali narod brojan i moćniji od nas."},{"v":10,"t":"Hajde, postupimo mudro s njima: spriječimo im porast, da se u slučaju rata ne pridruže našim neprijateljima, da ne udare na nas i napokon ne odu iz zemlje.”"},{"v":11,"t":"I postaviše nad njima nadglednike da ih tlače teškim radovima. Tako su faraonu sagradili gradove-skladišta: Pitom i Ramses."},{"v":12,"t":"Ali što su ih više tlačili, oni se još više množili, napredovali i širili se, tako da su Egipćani strahovali od Izraelaca."},{"v":13,"t":"I Egipćani se okrutno obore na Izraelce."},{"v":14,"t":"Ogorčavali su im život teškim radovima: pravljenjem meljte i opeke, različitim poljskim poslovima i svakovrsnim naporima koje im nemilosrdno nametahu."},{"v":15,"t":"Egipatski se kralj obrati i na hebrejske babice, od kojih jednoj bijaše ime Šifra, a drugoj Pua, pa im naredi:"},{"v":16,"t":"“Kad u porodu pomažete Hebrejkama, dobro pogledajte oba kamena sjedala: ako je muško dijete, ubijte ga; ako je žensko, neka živi."},{"v":17,"t":"Ali su se babice bojale Boga i nisu činile kako im je naredio egipatski kralj, nego su ostavljale na životu mušku djecu."},{"v":18,"t":"Stoga egipatski kralj pozove babice pa im rekne: “Zašto ste tako radile i na životu ostavljale mušku djecu?”"},{"v":19,"t":"Nato babice odgovore faraonu: “Hebrejke nisu kao egipatske žene. One su životne. Prije nego babica dođe k njima, one već rode.”"},{"v":20,"t":"Bog je to babicama za dobro primio. Narod se množio i silno porastao."},{"v":21,"t":"A kako su se babice bojale Boga, on ih obdari potomstvom."},{"v":22,"t":"Onda faraon izda naredbu svemu svome narodu: “Svako muško dijete koje se rodi Hebrejima bacite u Rijeku! Na životu ostavite samo žensku djecu.”"}]},"2":{"hr":[{"v":1,"t":"Neki čovjek od Levijeva koljena ode i oženi se djevojkom Levijkom."},{"v":2,"t":"Žena zače i rodi sina. Vidjevši kako je krasan, krila ga je tri mjeseca."},{"v":3,"t":"Kad ga nije mogla više sakrivati, nabavi košaricu od papirusove trstike, oblijepi je smolom i paklinom, u nju stavi dijete i položi ga u trstiku na obali Rijeke."},{"v":4,"t":"Njegova sestra stane podalje da vidi što će s njime biti."},{"v":5,"t":"Faraonova kći siđe k Rijeci da se kupa, dok su njezine sluškinje šetale uz obalu Rijeke. Opazi ona košaricu u trstici, pa pošalje sluškinju da je donese."},{"v":6,"t":"Otvori je i pogleda, a to u njoj dijete! Muško čedo. Plakalo je. Njoj se sažali na nj. “Bit će to hebrejsko dijete”, reče."},{"v":7,"t":"Onda njegova sestra rekne faraonovoj kćeri: “Hoćeš li da ti potražim dojilju među Hebrejkama da ti dijete doji?”"},{"v":8,"t":"“Idi!” - odgovori joj faraonova kći. Tako djevojka ode i pozove djetetovu majku."},{"v":9,"t":"“Uzmi ovo dijete”, rekne joj faraonova kći, “i odgoji mi ga, a ja ću te plaćati.” Tako žena uzme dijete i othrani ga."},{"v":10,"t":"Kad je dijete odraslo, ona ga odvede faraonovoj kćeri, koja ga posini. Nadjene mu ime Mojsije, “jer sam ga”, reče, “iz vode izvadila”."},{"v":11,"t":"Jednog dana, kad je Mojsije već odrastao, dođe među svoj narod i vidje njegove muke. Spazi tada kako neki Egipćanin tuče jednoga Hebrejca - brata njegova."},{"v":12,"t":"Okrene se tamo-amo i, vidjevši da nikoga nema, ubije Egipćanina i zatrpa ga u pijesak."},{"v":13,"t":"Izađe on i sutradan te zateče dva Hebrejca kako se tuku. “Zašto tučeš svoga druga?” - rekne napadaču."},{"v":14,"t":"Ovaj odvrati: “Tko te postavi za starješinu i suca našega? Kaniš li ubiti i mene kako si ubio onog Egipćanina?” Mojsije se uplaši pa će u sebi: “Tako! Ipak se saznalo.”"},{"v":15,"t":"Kad je faraon to dočuo, htjede Mojsija pogubiti. Zato Mojsije pobjegne od faraona i skloni se u midjansku zemlju. Ondje sjedne kraj nekog studenca."},{"v":16,"t":"Midjanski je svećenik imao sedam kćeri. Dođu one da zahvate vode i naliju pojila, da napoje stado svoga oca."},{"v":17,"t":"Ali dođu i pastiri te ih potjeraju. Mojsije ustane, obrani ih i stado im napoji."},{"v":18,"t":"Kad su se vratile svome ocu Reuelu, on ih zapita: “Kako ste se danas tako brzo vratile?”"},{"v":19,"t":"One odgovore: “Neki Egipćanin obrani nas od pastira i još nam zahvati vode i stado nam napoji.”"},{"v":20,"t":"“Gdje je?” - zapita on svoje kćeri. “Zašto ste ostavile toga čovjeka? Pozovite ga na objed.”"},{"v":21,"t":"Mojsije pristane da ostane kod toga čovjeka. On oženi Mojsija svojom kćeri Siporom."},{"v":22,"t":"A kad ona rodi sina, on mu nadjene ime Geršon, “jer sam”, reče, “stranac u tuđoj zemlji”."},{"v":23,"t":"Poslije mnogo vremena umre egipatski kralj. Izraelci su još stenjali u ropstvu. Vapili su, a njihov vapaj za pomoć sred ropstva uzlazio je k Bogu."},{"v":24,"t":"Bog je čuo njihovo zapomaganje i sjetio se svoga Saveza s Abrahamom, Izakom i Jakovom."},{"v":25,"t":"I pogleda Bog na Izraelce i zauze se za njih."}]},"3":{"hr":[{"v":1,"t":"Mojsije pasao ovce svoga tasta Jitra, midjanskoga svećenika. Goneći tako stado po pustari, dođe do Horeba, brda Božjega."},{"v":2,"t":"Anđeo mu se Jahvin ukaže u rasplamtjeloj vatri iz jednog grma. On se zagleda: grm sav u plamenu, a ipak ne izgara."},{"v":3,"t":"“Hajde da priđem, “ reče Mojsije, “i promotrim ovaj čudni prizor: zašto grm ne sagorijeva.”"},{"v":4,"t":"Kad je Jahve vidio kako prilazi da razmotri, iz grma ga Bog zovne: “Mojsije! Mojsije!” “Evo me!” - javi se."},{"v":5,"t":"“Ne prilazi ovamo!” - reče. “Izuj obuću s nogu! Jer mjesto na kojem stojiš sveto je tlo."},{"v":6,"t":"Ja sam”, nastavi, “Bog tvoga oca; Bog Abrahamov, Bog Izakov, Bog Jakovljev.” Mojsije zakloni lice: bojao se u Boga gledati."},{"v":7,"t":"“Vidio sam jade svoga naroda u Egiptu”, nastavi Jahve, “i čuo mu tužbu na tlačitelje njegove. Znane su mi muke njegove."},{"v":8,"t":"Zato sam sišao da ga izbavim iz šaka egipatskih i odvedem ga iz te zemlje u dobru i prostranu zemlju - u zemlju kojom teče med i mlijeko: u postojbinu Kanaanaca, Hetita, Amorejaca, Perižana, Hivijaca i Jebusejaca."},{"v":9,"t":"Vapaji sinova Izraelovih dopriješe do mene. I sam vidjeh kako ih Egipćani tlače."},{"v":10,"t":"Zato, hajde! Ja te šaljem faraonu da izbaviš narod moj, Izraelce, iz Egipta.”"},{"v":11,"t":"“Tko sam ja da se uputim faraonu”, odgovori Mojsije Bogu, “i izvedem Izraelce iz Egipta!”"},{"v":12,"t":"“Ja ću biti s tobom”, nastavi. “I ovo će ti biti znak da sam te ja poslao: kad izvedeš narod iz Egipta, Bogu ćete iskazati štovanje na ovome brdu.”"},{"v":13,"t":"Nato Mojsije reče Bogu: “Ako dođem k Izraelcima pa im kažem: 'Bog otaca vaših poslao me k vama', i oni me zapitaju: 'Kako mu je ime?' - što ću im odgovoriti?”"},{"v":14,"t":"“Ja sam koji jesam”, reče Bog Mojsiju. Onda nastavi: “Ovako kaži Izraelcima: 'Ja jesam' posla me k vama.”"},{"v":15,"t":"Dalje je Bog Mojsiju rekao: “Kaži Izraelcima ovako: 'Jahve, Bog vaših otaca, Bog Abrahamov, Bog Izakov i Bog Jakovljev, poslao me k vama.' To mi je ime dovijeka, tako će me zvati od koljena do koljena.”"},{"v":16,"t":"“Idi, skupi starješine Izraelaca pa im kaži: 'Jahve, Bog otaca - Bog Abrahamov, Izakov i Jakovljev - objavio mi se i rekao mi: Pohodio sam vas i razabrao što vam se čini u Egiptu."},{"v":17,"t":"Odlučio sam vas izvesti iz egipatske bijede u zemlju Kanaanaca, Hetita, Amorejaca, Perižana, Hivijaca i Jebusejaca - u zemlju kojom teče med i mlijeko!'"},{"v":18,"t":"Oni će te poslušati. Onda pođi sa starješinama Izraelaca k egipatskom kralju i reci mu: 'Objavio nam se Jahve, Bog Hebreja. Pusti nas da odemo tri dana hoda u pustinju, da ondje prinesemo žrtvu Jahvi, Bogu svojemu.'"},{"v":19,"t":"Znam ja da vas egipatski kralj neće pustiti ako ne bude natjeran teškom šakom."},{"v":20,"t":"Zato ću ja pružiti svoju šaku i pritisnuti Egipat svakovrsnim čudesima što ću ih u njemu izvesti. Poslije će vas pustiti."},{"v":21,"t":"Dobro ću raspoložiti Egipćane prema ovome narodu, pa kad pođete, nećete poći praznih ruku."},{"v":22,"t":"Svaka će žena zatražiti od svoje susjede i stanarke u svojoj kući nakita srebrnog i zlatnog i odjeće. To stavite na svoje sinove i kćeri. Tako ćete oplijeniti Egipćane.”"}]},"4":{"hr":[{"v":1,"t":"Mojsije uzvrati: “Ali ako mi ne povjeruju i ne poslušaju me, nego mi reknu: 'Jahve ti se nije objavio?'”"},{"v":2,"t":"“Što ti je to u ruci?” - zapita ga Jahve. “Štap”, odgovori."},{"v":3,"t":"“Baci ga na zemlju!” - naredi mu Jahve. On ga baci na zemlju, a štap se pretvori u zmiju. Mojsije pred njom uzmače."},{"v":4,"t":"Onda Jahve reče Mojsiju: “Pruži ruku i uhvati je za rep.” I on seže rukom i uhvati je za rep, a ona opet postade štap u njegovoj ruci."},{"v":5,"t":"“Tako moraju vjerovati da se Jahve, Bog njihovih otaca, Bog Abrahamov, Bog Izakov i Bog Jakovljev, tebi objavio.”"},{"v":6,"t":"Još mu Jahve rekne: “Uvuci ruku u njedra.” On uvuče ruku u njedra. Kad ju je izvukao, gle - ruka mu gubava, bijela kao snijeg."},{"v":7,"t":"“Stavi opet ruku u njedra!” - naredi mu Jahve. On opet ruku u njedra. Kad ju je iz njedara izvukao, gle - opet je bila kao i ostali dio tijela."},{"v":8,"t":"“Ako ti ne povjeruju i ne prihvate poruku prvoga znamenja, povjerovat će poruci drugoga znamenja."},{"v":9,"t":"A ako ih oba ova znamenja ne uvjere pa ti ne povjeruju, zahvati vode iz Rijeke i prolij je po suhu. Voda što je budeš iz Rijeke uzeo na suhu će se u krv pretvoriti.”"},{"v":10,"t":"“Oprosti, Gospodine!” - nastavi Mojsije Jahvi. “Ja nikad nisam bio čovjek rječit; ni prije ni sada kad govoriš svome sluzi. Ja sam u govoru spor, a na jeziku težak.”"},{"v":11,"t":"“Tko je dao čovjeku usta?” - reče mu Jahve. “Tko ga čini nijemim i gluhim; tko li mu vid daje ili ga osljepljuje? Zar to nisam ja, Jahve!"},{"v":12,"t":"Idi, dakle! Ja ću biti s tobom kad budeš govorio i kazivat ću ti što ćeš govoriti.”"},{"v":13,"t":"“Oprosti, Gospodine”, opet će Mojsije, “ne bi li poslao koga drugoga!”"},{"v":14,"t":"Razljuti se Jahve na Mojsija i reče: “Zar Aron, Levijevac, nije tvoj brat? Znam da je on vrlo rječit. Evo, baš ti izlazi u susret. Kad te vidi, obradovat će se u srcu."},{"v":15,"t":"Ti govori njemu i u njegova usta stavljaj riječi. Ja ću biti i s tobom i s njime dok budete govorili; kazivat ću obojici što ćete raditi."},{"v":16,"t":"Neka on mjesto tebe govori narodu. Tako, on će tebi biti mjesto usta, a ti ćeš njemu biti mjesto Boga."},{"v":17,"t":"Uzmi ovaj štap u ruku. Njim izvodi znamenja.”"},{"v":18,"t":"Zatim se Mojsije vrati svome tastu Jitru te mu reče: “Pusti me da se vratim braći u Egipat da vidim jesu li još na životu.” “Pođi u miru!” - reče Jitro Mojsiju."},{"v":19,"t":"I Jahve reče Mojsiju u Midjanu: “Vrati se u Egipat, jer su pomrli svi ljudi koji su tražili tvoj život.”"},{"v":20,"t":"Tako Mojsije posadi na magarca svoju ženu i sinove i ode u zemlju egipatsku. A u ruku Mojsije uze Božji štap."},{"v":21,"t":"Jahve opet reče Mojsiju: “Kad se vratiš u Egipat, pobrini se da pred faraonom izvedeš sva čudesa za koja sam ti dao moć, premda ću ja tvrdim učiniti njegovo srce, tako te neće pustiti narod da ode."},{"v":22,"t":"Tada reci faraonu: 'Ovako kaže Jahve: Izrael je moj prvorođenac."},{"v":23,"t":"Tražim od tebe da mi pustiš sina da mi iskaže štovanje. Ako odbiješ da ga pustiš, ja ću ubiti tvoga prvorođenca.'”"},{"v":24,"t":"Kad se na putu Mojsije zaustavi da prenoći, navali na nj Jahve da ga ubije."},{"v":25,"t":"Ali Sipora pograbi oštar kremen, obreza svoga sina i kožicom se dotakne Mojsijevih nogu: “Zaista si mi ti krvav muž”, reče."},{"v":26,"t":"I Jahve ga pusti. Ona je to zbog obrezanja rekla “krvav muž”."},{"v":27,"t":"Onda rekne Jahve Aronu: “Zaputi se prema pustinji, u susret Mojsiju!” On ode i s njim se sastane na Božjem brdu. Poljubi ga."},{"v":28,"t":"Mojsije pripovjedi Aronu sve što mu je Jahve povjerio i sva znamenja koja mu je naredio da ih učini."},{"v":29,"t":"Sad odu Mojsije i Aron i skupe sve starješine Izraelaca."},{"v":30,"t":"Aron izloži sve što je Jahve govorio Mojsiju, a Mojsije izvede znamenja naočigled naroda."},{"v":31,"t":"Narod je bio uvjeren, i pošto čuše da je Jahve pohodio Izraelce i pogledao na njihove jade, popadaše ničice i pokloniše se."}]},"5":{"hr":[{"v":1,"t":"Poslije toga odu Mojsije i Aron pa reknu faraonu: “Ovako veli Jahve, Bog Izraelov: 'Pusti narod moj da ode i u moju čast slavi svetkovinu.'”"},{"v":2,"t":"“Tko je taj Jahve da ga ja poslušam”, odvrati faraon, “i pustim Izraelce? Ja toga Jahvu ne znam niti ću pustiti Izraelce.”"},{"v":3,"t":"“Bog Hebreja objavio nam se”, rekoše. “Zato nas pusti da odemo tri dana hoda u pustinju i prinesemo žrtvu Jahvi, Bogu svome, da se na nas ne obori pomorom ili mačem.”"},{"v":4,"t":"Nato im odvrati egipatski kralj: “Mojsije i Arone, zašto odvraćate svijet od njegovih dužnosti? Idite na svoj posao."},{"v":5,"t":"Sad kad se svjetina tako umnožila”, nastavi faraon, “vi biste ih od posla odvratili?”"},{"v":6,"t":"Istoga dana izda faraon naredbu nadglednicima i bilježnicima:"},{"v":7,"t":"“Ne pribavljajte više ovome narodu slame kao do sada. Neka idu sami i sebi je skupljaju."},{"v":8,"t":"A zahtijevajte od njih istu količinu opeke koju su pravili i dosad. Ne smanjujte je! Lijenčine su. Zato viču: 'Hajdemo prinijeti žrtvu Bogu svome!'"},{"v":9,"t":"Navalite poslove na taj svijet: neka rade, da ne obraćaju pažnje klevetama!”"},{"v":10,"t":"Sad dođu nadglednici naroda i njegovi bilježnici te svijetu objave: “Ovako poručuje faraon: 'Neću vam više nabavljati slame."},{"v":11,"t":"Vi sami morate ići i tražiti je gdje god je možete naći. Ali zato neću smanjiti vaš posao.'”"},{"v":12,"t":"Stoga se narod raziđe po svoj zemlji egipatskoj da skuplja strnjiku namjesto slame."},{"v":13,"t":"A nadglednici ih gonili: “Morate svakoga dana svršiti jednako posla kao i onda dok ste slamu dobivali.”"},{"v":14,"t":"A bilježnike koje faraonovi nadglednici bijahu postavili nad Izraelcima tukli su i korili: “Zašto niste ni jučer ni danas napravili opeke koliko i prije?”"},{"v":15,"t":"Onda bilježnici Izraelaca odu i potuže se faraonu: “Zašto ovako postupaš sa svojim slugama?"},{"v":16,"t":"Tvoje sluge više ne dobivaju slame, a ipak se od nas traži: napravite opeku? Čak i tuku tvoje sluge, a kriv je tvoj narod!”"},{"v":17,"t":"“Lijenčine ste vi! Lijenčine!” - odgovori faraon. “Stoga i kažete: 'Hajdemo da prinesemo žrtvu Jahvi!'"},{"v":18,"t":"Nosite se na posao! Slama vam se neće davati, ali morate praviti određene količine opeke.”"},{"v":19,"t":"Bilježnici Izraelaca nađu se na muci zbog naredbe: “Svakodnevnu količinu opeke ne smijete smanjiti!”"},{"v":20,"t":"Otišavši od faraona, naiđu na Mojsija i Arona, koji su ih čekali."},{"v":21,"t":"“Neka vas Jahve ima na oku i sudi vam!” - dobace im. “Omrazili ste nas kod faraona i njegovih dvorana; dali ste im mač u ruke da nas pobiju.”"},{"v":22,"t":"Mojsije se vrati Jahvi i reče: “Zašto, Gospodine, nanosiš štetu svome puku? Zašto si me poslao?"},{"v":23,"t":"Otkad sam ja stupio pred faraona i progovorio mu u tvoje ime, on još gore postupa s ovim narodom. A ti ništa ne poduzimaš da izbaviš svoj narod.”"}]},"6":{"hr":[{"v":1,"t":"Jahve reče Mojsiju: “Naskoro ćeš vidjeti kako ću ja s faraonom! Pod jakom rukom pustit će ih da odu; pod jakom rukom sam će ih iz svoje zemlje istjerati.”"},{"v":2,"t":"Još reče Bog Mojsiju: “Ja sam Jahve."},{"v":3,"t":"Abrahamu, Izaku i Jakovu objavljivao sam se kao El Šadaj. Ali njima se nisam očitovao pod svojim imenom - Jahve."},{"v":4,"t":"I sklopio sam svoj Savez s njima da ću im dati kanaansku zemlju, zemlju gdje su živjeli kao pridošlice."},{"v":5,"t":"A sada, pošto sam čuo uzdisaje Izraelaca koje Egipćani drže u ropstvu, sjetih se svoga Saveza."},{"v":6,"t":"Kaži, dakle, Izraelcima da sam ja Jahve; da ću vas izbaviti od tereta što su vam ga Egipćani nametnuli. Oslobodit ću vas od ropstva u kojem vas drže; izbavit ću vas udarajući jako i kažnjavajući strogo."},{"v":7,"t":"Za svoj ću vas narod uzeti i bit ću vašim Bogom. Tada ćete znati da sam vas ja, Jahve, vaš Bog, izbavio od egipatske tlake."},{"v":8,"t":"Dovest ću vas u zemlju za koju sam se zakleo da ću je dati Abrahamu, Izaku i Jakovu i dat ću vam je u baštinu, ja, Jahve.”"},{"v":9,"t":"Mojsije to kazivaše Izraelcima, ali ga ne htjedoše slušati: duhovi su im bili pomućeni od teškoga ropstva."},{"v":10,"t":"Onda Jahve reče Mojsiju:"},{"v":11,"t":"“Idi i reci faraonu, kralju egipatskome, da otpusti Izraelce iz svoje zemlje.”"},{"v":12,"t":"Mojsije prozbori Jahvi: “Kad me Izraelci nisu slušali, kako će me, spora u govoru, saslušati faraon!”"},{"v":13,"t":"Ali je Jahve govorio Mojsiju i Aronu i slao ih sad k Izraelcima, a sad k faraonu, kralju egipatskome, da pusti Izraelce iz Egipta."},{"v":14,"t":"Ovo su glave njihovih domova. Sinovi Izraelova prvorođenca Rubena: Henok, Palu, Hesron i Karmi. To su obitelji potekle od Rubena."},{"v":15,"t":"A sinovi Šimunovi: Jemuel, Jamin, Ohad, Jakin, Sohar i Šaul, sin Kanaanke. To su obitelji potekle od Šimuna."},{"v":16,"t":"Ovo su imena Levijevih sinova s njihovim potomstvom: Geršon, Kehat i Merari. Levi je živio sto trideset i sedam godina."},{"v":17,"t":"Sinovi su Geršonovi: Libni i Šimi sa svojim obiteljima."},{"v":18,"t":"Sinovi su Kehatovi: Amram, Jishar, Hebron i Uziel. Kehat je živio sto trideset i tri godine."},{"v":19,"t":"Merarijevi su sinovi: Mahli i Muši. To su Levijeve obitelji s njihovim potomcima."},{"v":20,"t":"Amram se oženi svojom tetkom Jokebedom, koja mu rodi Arona i Mojsija. Amram je živio sto trideset i sedam godina."},{"v":21,"t":"Sinovi Jisharovi bijahu: Korah, Nefeg i Zikri."},{"v":22,"t":"A sinovi su Uzielovi: Mišael, Elsafan i Sitri."},{"v":23,"t":"Aron se oženi Elišebom, kćerkom Aminadabovom, a sestrom Nahšonovom, koja mu rodi: Nadaba, Abihua, Eleazara i Itamara."},{"v":24,"t":"Korahovi su sinovi: Asir, Elkana i Abiasaf. To su Korahovi potomci."},{"v":25,"t":"Aronov sin Eleazar oženi se jednom Putielovom kćeri, koja mu rodi Pinhasa. To su glave Levijevih domova prema njihovim koljenima."},{"v":26,"t":"To je onaj Aron i Mojsije kojima je Jahve zapovjedio da izvedu Izraelce iz Egipta po njihovim četama."},{"v":27,"t":"To su oni isti, Mojsije i Aron, koji su govorili faraonu, kralju egipatskome, da pusti Izraelce iz Egipta."},{"v":28,"t":"U dan kad je Jahve govorio s Mojsijem u egipatskoj zemlji,"},{"v":29,"t":"rekao mu je: “Ja sam Jahve. Izvijesti faraona, egipatskoga kralja, o svemu što ti kažem.”"},{"v":30,"t":"Mojsije se pred Jahvom ispričavao: “Spor sam ja u govoru. Kako će me faraon poslušati?”"}]},"7":{"hr":[{"v":1,"t":"Mojsiju je Jahve odgovorio: “Vidi! Faraonu ću te nametnuti kao božanstvo; tvoj brat Aron bit će tvoj prorok."},{"v":2,"t":"Ti kazuj sve što ti naređujem, a tvoj brat Aron neka faraonu ponovi da pusti Izraelce te odu iz njegove zemlje."},{"v":3,"t":"Ja ću učiniti da otvrdne srce faraonu i umnožit ću znakove i čudesa u zemlji egipatskoj."},{"v":4,"t":"Kako vas faraon neće poslušati, ja ću staviti svoju ruku na Egipat: strašno kažnjavajući, izbavit ću svoje čete, narod svoj, Izraelce, iz egipatske zemlje."},{"v":5,"t":"Kad pružim svoju ruku na Egipat i izvedem Izraelce iz njihove sredine, tada će Egipćani spoznati da sam ja Jahve.”"},{"v":6,"t":"Mojsije i Aron poslušaše: kako im je Jahve naredio, upravo tako učiniše."},{"v":7,"t":"Mojsiju je bilo osamdeset, a Aronu osamdeset i tri godine kad su faraonu postavili svoje zahtjeve."},{"v":8,"t":"Još doda Jahve Mojsiju i Aronu:"},{"v":9,"t":"“Kad faraon zatraži od vas da izvedete kakvo znamenje, ti reci Aronu da uzme svoj štap i baci ga pred faraona, a štap će se pretvoriti u zmiju.”"},{"v":10,"t":"Dođu Mojsije i Aron pred faraona i učine kako im je Jahve naredio. Aron baci pred faraona i njegove službenike svoj štap, koji se pretvori u zmiju."},{"v":11,"t":"Zovne faraon mudrace i vračare. I zaista, egipatski vračari svojim vračanjem učine isto:"},{"v":12,"t":"svaki baci svoj štap, koji se pretvori u zmiju. Ali Aronov štap proguta njihove štapove."},{"v":13,"t":"Faraon bijaše tvrdokorna srca: ne htjede poslušati Mojsija i Arona, kako je Jahve i kazao."},{"v":14,"t":"Tada Jahve reče Mojsiju: “Faraonovo je srce okorjelo; odbija da pusti narod."},{"v":15,"t":"Ujutro pođi k faraonu. Kad izađe k vodi, stani preda nj na obali Rijeke. Uzmi u ruku štap što se bio u zmiju pretvorio."},{"v":16,"t":"Reci mu: 'Jahve, Bog Hebreja, poslao me k tebi s porukom da pustiš moj narod da mi iskaže štovanje u pustinji. Ali sve dosad ti nisi poslušao."},{"v":17,"t":"Ovako Jahve poručuje: Ovim ćeš spoznati da sam ja Jahve. Gledaj! Štapom koji imam u ruci mlatnut ću po vodi u Rijeci i pretvorit će se u krv."},{"v":18,"t":"Ribe će u Rijeci pocrkati; Rijeka će se usmrdjeti, i grstit će se Egipćanima piti vodu iz Rijeke.'”"},{"v":19,"t":"Još Jahve reče Mojsiju: “Reci Aronu da uzme svoj štap i pruži svoju ruku povrh egipatskih voda: njihovih rijeka, njihovih prokopa, njihovih jezeraca, svih njihovih vodenih stjecišta, da se pretvore u krv; po svoj zemlji egipatskoj neka je krv, čak i u drvenim i kamenim posudama.”"},{"v":20,"t":"Mojsije i Aron učiniše kako im je Jahve naredio. Podiže Aron svoj štap i naočigled faraona i njegovih službenika mlatnu po vodi u Rijeci. Sva se voda u Rijeci prometnu u krv."},{"v":21,"t":"Ribe u Rijeci pocrkaše; Rijeka se usmrdje, tako da Egipćani nisu mogli piti vodu iz Rijeke; krv bijaše po svoj zemlji egipatskoj."},{"v":22,"t":"Ali egipatski vračari svojim vračanjem učiniše isto. Tako faraon ostade tvrdokorna srca: nije htio poslušati Mojsija i Arona, kako je Jahve i kazao."},{"v":23,"t":"Faraon se okrenu i ode u svoj dvor, ne uzimajući ni to k srcu."},{"v":24,"t":"Svi su Egipćani počeli kopati oko Rijeke tražeći pitke vode jer nisu mogli piti vode iz Rijeke."},{"v":25,"t":"Kad je prošlo sedam dana kako je Jahve udario po Rijeci,"},{"v":26,"t":"opet Jahve reče Mojsiju: “Pođi k faraonu i reci mu: 'Ovako govori Jahve: Pusti moj narod da ode i štovanje mi iskaže."},{"v":27,"t":"Ako odbiješ da ih pustiš, svu ću ti zemlju kazniti žabama."},{"v":28,"t":"Rijeka će vrvjeti žabama. One će izići i prodrijeti u tvoj dvor, u ložnicu, u tvoju postelju, u kuće tvojih službenika i tvoga naroda, pod sačeve i naćve tvoje."},{"v":29,"t":"Po tebi, po tvome narodu i svim tvojim službenicima skakat će žabe.'”"}]},"8":{"hr":[{"v":1,"t":"Onda Jahve reče Mojsiju: “Reci Aronu neka ispruži svoju ruku sa štapom povrh rijeka, prokopa i jezeraca i učini da žabe navale na egipatsku zemlju.”"},{"v":2,"t":"Aron pruži svoju ruku povrh egipatskih voda, i žabe iziđoše i prekriše zemlju egipatsku."},{"v":3,"t":"Ali i vračari učiniše tako svojim vračanjem, te žabe navališe na egipatsku zemlju."},{"v":4,"t":"Zovne sad faraon Mojsija i Arona i rekne: “Molite Jahvu da ukloni žabe od mene i moga puka, a ja ću pustiti narod da prinese žrtvu Jahvi.”"},{"v":5,"t":"Mojsije uzvrati faraonu: “Dostoj se odrediti mi kad hoćeš da molim za te, za tvoje službenike i za tvoj narod da se žabe odstrane od tebe i tvojih domova i ostanu samo u Rijeci.”"},{"v":6,"t":"“Sutra”, reče. “Neka bude kako kažeš”, odvrati Mojsije, “da znaš kako nitko nije kao Jahve, Bog naš."},{"v":7,"t":"Žabe će otići od tebe, od tvojih službenika i tvoga naroda; ostat će samo u Rijeci.”"},{"v":8,"t":"Mojsije i Aron odu od faraona, a onda Mojsije zazva Jahvu zbog žaba kojima je kaznio faraona."},{"v":9,"t":"I Jahve usliša Mojsija, te žabe pocrkaju po kućama, dvorištima i njivama."},{"v":10,"t":"Na hrpe su ih zgrtali, zemlja se njima usmrdjela."},{"v":11,"t":"Kad je faraon vidio da je nastupilo olakšanje, srce mu otvrdnu te ne posluša Mojsija i Arona, kako je Jahve i kazao."},{"v":12,"t":"Onda će opet Jahve Mojsiju: “Reci Aronu neka zamahne svojim štapom i udari po prahu na tlu neka se pretvori u komarce po svoj zemlji egipatskoj.”"},{"v":13,"t":"I učine tako: zamahne Aron rukom i štapom te udari po prahu na tlu. Komarci navale na ljude i životinje. Sav prah na tlu pretvori se u komarce po svoj zemlji egipatskoj."},{"v":14,"t":"Vračari pokušaše da svojim vračanjem stvore komarce, ali nisu mogli. Ljudi i životinje postanu plijenom komaraca."},{"v":15,"t":"Tada vračari reknu faraonu: “To je prst Božji!” Ali je faraonovo srce bilo okorjelo, pa nije poslušao Mojsija i Arona, kako je Jahve i kazao."},{"v":16,"t":"Onda Jahve reče Mojsiju: “Podrani ujutro, iziđi pred faraona kad krene k vodi, i reci mu: 'Ovako poručuje Jahve: Pusti moj narod da ode i da mi štovanje iskaže."},{"v":17,"t":"Ako ne pustiš moga naroda, pripustit ću obade na te, na tvoje službenike, na tvoj puk i tvoje domove. Egipatski domovi i samo tlo na kojem stoje vrvjet će od obada."},{"v":18,"t":"Ali ću toga dana izuzeti gošenski kraj, u kojem živi moj narod, te se ondje obadi neće pojaviti, tako da znaš da sam ja Jahve u središtu zemlje."},{"v":19,"t":"Tu ću razliku napraviti između svoga i tvoga naroda. To će znamenje biti sutra.'”"},{"v":20,"t":"I učini Jahve tako. Rojevi obada nalete u faraonov dvor, na domove njegovih službenika i po svoj zemlji egipatskoj. Zemlja nastrada od obada."},{"v":21,"t":"Sad faraon pozove Mojsija i Arona pa im rekne: “Idite, prinesite žrtvu svome Bogu, ali u ovoj zemlji.”"},{"v":22,"t":"“Ne dolikuje da tako učinimo”, odgovori Mojsije. “Žrtve koje mi prinosimo Jahvi, Bogu svome, za Egipćane su svetogrđe. Kad bismo, dakle, na njihove oči prinosili žrtve koje su Egipćanima svetogrdne, zar nas ne bi kamenovali?"},{"v":23,"t":"Zato moramo u pustinju tri dana hoda te prinijeti žrtvu Jahvi, Bogu svome, kako nam je zapovjedio.”"},{"v":24,"t":"“Pustit ću vas da odete u pustinju”, odgovori faraon, “i prinesete žrtvu Jahvi, svome Bogu, ali ne odlazite predaleko. Molite za me!”"},{"v":25,"t":"Nato odvrati Mojsije: “Čim odem od tebe, zazvat ću Jahvu da sutra nestane obada s faraona, njegovih službenika i njegova puka. Ali neka faraon više ne vara! Neka pusti narod da ide i prinese žrtvu Jahvi.”"},{"v":26,"t":"Tako Mojsije ode od faraona i pomoli se Jahvi."},{"v":27,"t":"I Jahve učini kako je Mojsije tražio: s faraona, s njegovih službenika i s njegova puka nestane obada - ni jedan jedini nije ostao."},{"v":28,"t":"Ali opet ukruti faraon srce svoje i ne dopusti narodu da ode."}]},"9":{"hr":[{"v":1,"t":"Tada Jahve reče Mojsiju: “Idi k faraonu i reci mu: 'Ovako poručuje Jahve, Bog Hebreja: Pusti moj narod da ode i da mi štovanje iskaže."},{"v":2,"t":"Ako ga ne pustiš, nego ga i dalje budeš zadržavao,"},{"v":3,"t":"ruka Jahvina udarit će strašnim pomorom po tvome blagu što je u polju: po konjima, magaradi, devama, krupnoj i sitnoj stoci."},{"v":4,"t":"Razlikovat će Jahve stoku Izraelaca od stoke Egipćana, tako da ništa što pripada Izraelcima neće stradati.'”"},{"v":5,"t":"Jahve je odredio i vrijeme, rekavši: “Sutra će Jahve izvesti ovo u zemlji.”"},{"v":6,"t":"Sutradan Jahve tako i učini. Sva stoka Egipćana ugine, a od stoke Izraelaca nije uginulo ni jedno grlo."},{"v":7,"t":"Faraon je istraživao i uvjerio se da od izraelske stoke nije uginulo ni jedno grlo. Ali je srce faraonovo ipak otvrdlo i nije pustio naroda."},{"v":8,"t":"Reče Jahve Mojsiju i Aronu: “Zagrabite pune pregršti pepela iz peći, pa neka ga Mojsije pred faraonovim očima baci prema nebu."},{"v":9,"t":"Od toga će nastati sitna prašina po svoj zemlji egipatskoj, i na ljudima će i na životinjama izazivati otekline i stvarati čireve s kraja na kraj Egipta.”"},{"v":10,"t":"Tako oni uzeše pepela iz peći i dođoše pred faraona. Onda Mojsije rasu pepeo prema nebu, a otekline s čirevima prekriše ljude i životinje."},{"v":11,"t":"Ni čarobnjaci se nisu mogli pojaviti pred Mojsijem, jer su i čarobnjaci, kao i ostali Egipćani, bili prekriveni čirevima."},{"v":12,"t":"Ali je Jahve otvrdnuo srce faraonu, pa on ne posluša Mojsija i Arona, kako je Jahve Mojsiju i rekao."},{"v":13,"t":"Tada Jahve reče Mojsiju: “Podrani ujutro, iziđi pred faraona i reci mu: 'Ovako poručuje Jahve, Bog Hebreja: Pusti narod da ode i da mi štovanje iskaže."},{"v":14,"t":"Ako ih ne pustiš, sva zla svoja navalit ću ovaj put na te, na tvoje službenike i tvoj puk, tako da spoznaš da nema nikoga na svoj zemlji kao što sam ja."},{"v":15,"t":"Da sam ruku svoju spustio i udario tebe i tvoj puk pomorom, nestalo bi te sa zemlje."},{"v":16,"t":"Poštedio sam te da ti pokažem svoju moć i da se hvali moje ime po svoj zemlji."},{"v":17,"t":"Ali se ti previše uzdižeš nad mojim narodom i priječiš mu da ode."},{"v":18,"t":"Sutra u ovo doba pustit ću tuču tako strašnu kakve u Egiptu još nije bilo otkad je postao do sada."},{"v":19,"t":"Zato naredi da pod krov utjeraju tvoje blago i sve što je vani, na otvorenu. Sve što se nađe u polju, bilo čovjek bilo živinče, ne bude li uvedeno unutra, poginut će kad tuča zaspe po njima.'”"},{"v":20,"t":"Faraonovi službenici, koji su se pobojali Jahvina govora, utjeraju svoje sluge i svoje blago unutra."},{"v":21,"t":"Oni koji nisu marili za Jahvinu prijetnju ostave vani i svoje sluge i stoku."},{"v":22,"t":"Onda rekne Jahve Mojsiju: “Pruži ruku prema nebu da udari tuča po svoj zemlji egipatskoj: po ljudima, životinjama i svemu bilju u zemlji egipatskoj.”"},{"v":23,"t":"Mojsije diže svoj štap prema nebu. Jahve zagrmje i pusti tuču i munje sastavi sa zemljom. Sipao je Jahve tuču po zemlji Egipćana."},{"v":24,"t":"Tuča je mlatila, kroz nju munje parale. Strahota se takva nije oborila na zemlju egipatsku otkako su ljudi u njoj."},{"v":25,"t":"Tuča pobi po svem Egiptu sve što je ostalo vani, ljude i životinje; uništi sve bilje po poljima i sva stabla poljska polomi."},{"v":26,"t":"Samo u gošenskom kraju, gdje su živjeli Izraelci, nije bilo tuče."},{"v":27,"t":"Faraon posla po Mojsija i Arona pa im reče: “Ovaj put priznajem da sam kriv. Jahve ima pravo, a ja i moj narod krivo."},{"v":28,"t":"Molite Jahvu da ustavi gromove i tuču, a ja ću vas pustiti da idete. Nećete više dugo ostati.”"},{"v":29,"t":"“Kad iziđem iz grada”, reče mu Mojsije, “dići ću ruke prema Jahvi, pa će gromovi prestati, a ni tuče više neće biti, tako da znaš da zemlja pripada Jahvi."},{"v":30,"t":"Ali ni ti ni tvoji dvorani, znam ja, još se ne bojite Boga Jahve.”"},{"v":31,"t":"I tako propade lan i ječam: jer ječam bijaše u klasu, a lan u cvatu."},{"v":32,"t":"Pšenica i raž nisu nastradali jer su ozima žita."},{"v":33,"t":"Otišavši od faraona, Mojsije iziđe iz grada i podigne ruke prema Jahvi. Prestane grmljavina i tuča, a ni kiša više nije padala na zemlju."},{"v":34,"t":"Kad je faraon vidio da je prestala grmljavina, tuča i kiša, opet padne u grijeh: i on i njegovi službenici opet otvrdnu srcem."},{"v":35,"t":"Otvrdnu srce faraonu i ne pusti on Izraelce, kako je Jahve i prorekao preko Mojsija."}]},"10":{"hr":[{"v":1,"t":"Reče Jahve Mojsiju: “Idi k faraonu. Učinio sam da njemu i njegovim službenicima otvrdne srce da izvedem svoja znamenja među njima;"},{"v":2,"t":"da možeš pripovjedati svome sinu i svome unuku što sam učinio Egipćanima i kakva sam znamenja izvodio među njima, kako biste znali da sam ja Jahve.”"},{"v":3,"t":"Tako Mojsije i Aron odu k faraonu i kažu mu: “Ovako poručuje Jahve, Bog Hebreja: 'Dokle ćeš odbijati da se preda mnom poniziš? Pusti moj narod da mi iskaže štovanje."},{"v":4,"t":"Jer ako ne pustiš moga naroda, sutra ću navesti skakavce na tvoju zemlju."},{"v":5,"t":"Tako će prekriti površinu da se zemlja od njih neće vidjeti. Pojest će ono što vam je iza tuče ostalo; i ogolit će vam sva stabla što po polju rastu."},{"v":6,"t":"Ispunit će ti sav dvor, kuće tvojih službenika i domove svih ostalih Egipćana - takvo što ne vidješe ni tvoji očevi ni očevi tvojih očeva u ovoj zemlji od svojih vremena do danas.'” Okrene se i ode od faraona."},{"v":7,"t":"“Dokle će nam ovaj čovjek biti stupica?” - rekoše faraonu njegovi službenici. - “Pusti te ljude neka idu i iskažu štovanje Jahvi, svome Bogu! Zar ne vidiš kako Egipat srlja u propast?”"},{"v":8,"t":"Dovedu Mojsija i Arona natrag k faraonu, a on im reče: “Idite! Iskažite štovanje Jahvi, svome Bogu! A tko će sve ići?”"},{"v":9,"t":"“Svi idemo”, odgovori Mojsije, “i mlado i staro. Odlazimo sa svojim sinovima i svojim kćerima; sa svojom krupnom i sitnom stokom, jer moramo održati svečanost Jahvi.”"},{"v":10,"t":"“Jahve bio s vama isto kao što i ja pustio da s vama pođu i djeca!” - odgovori im. “Očito se vidi da vam nakana nije čista."},{"v":11,"t":"Nećemo tako! Nego muškarci neka odu i štovanje iskažu Jahvi. To ste i tražili.” I otjeraju ih od faraona."},{"v":12,"t":"Tada reče Jahve Mojsiju: “Pruži ruku povrh zemlje egipatske da navale skakavci na egipatsku zemlju i pojedu sve bilje što još ostade nakon tuče!”"},{"v":13,"t":"Tako Mojsije podigne svoj štap povrh egipatske zemlje, a Jahve navrati istočni vjetar po zemlji; puhao je toga cijelog dana i cijele noći. A kad je jutro svanulo, vjetar nanio skakavce."},{"v":14,"t":"Oni se razlete po svoj egipatskoj zemlji i padnu po svim krajevima Egipta u silnoj gustoći: toliko ih mnoštvo nikad prije nije bilo niti će kada biti."},{"v":15,"t":"Pokriju sve tlo, tako da se od njih zacrnjelo. Pojedu sve bilje u polju i sve plodove sa stabala što su bili ostali iza tuče. Ništa se više nije zelenjelo: ni stabla ni poljska trava u svem Egiptu."},{"v":16,"t":"Brže-bolje dozva faraon Mojsija i Arona pa im reče: “Sagriješio sam protiv Jahve, vašega Boga, i vas!"},{"v":17,"t":"Oprostite mi uvredu još samo ovaj put i molite Jahvu, Boga svoga, da samo otkloni od mene ovaj smrtonosni bič!”"},{"v":18,"t":"Kad je Mojsije otišao od faraona, zazva Jahvu"},{"v":19,"t":"i Jahve promijeni vjetar u veoma jak zapadnjak, koji pothvati skakavce i odnese prema Crvenome moru. Ni jedan jedini skakavac nije ostao ni u kojem kraju Egipta."},{"v":20,"t":"Ali je Jahve otvrdnuo srce faraonu i ne pusti on Izraelaca."},{"v":21,"t":"“Pruži ruku prema nebu”, rekne Jahve Mojsiju, “pa neka se tmina spusti na egipatsku zemlju, tmina koja će se moći opipati.”"},{"v":22,"t":"Mojsije pruži ruku prema nebu i spusti se gusta tmina na svu zemlju egipatsku: tri je dana trajala."},{"v":23,"t":"Tri dana nisu ljudi jedan drugoga mogli vidjeti i nitko se sa svoga mjesta nije micao. A u mjestima gdje su Izraelci živjeli sjala svjetlost."},{"v":24,"t":"Pozva onda faraon Mojsija i reče: “Idi i štovanje iskaži Jahvi! Ali vaša stoka, krupna i sitna, neka ostane ovdje. Vaša djeca neka idu s vama!”"},{"v":25,"t":"“Ti nas sam moraš opskrbiti prinosima i žrtvama paljenicama koje ćemo prinijeti Jahvi, Bogu svojemu”, odgovori Mojsije."},{"v":26,"t":"“Zato ćemo sa sobom potjerati i svoja stada. Ni papak neće ostati ovdje. Od njih nam valja izabrati za žrtvovanje Jahvi, Bogu našemu, a ne znamo, dok onamo ne stignemo, što moramo Jahvi prinijeti.”"},{"v":27,"t":"Jahve otvrdne faraonu srce i on ne pristane da odu."},{"v":28,"t":"“Odlazi!” - vikne faraon na Mojsija. “I da mi više na oči ne dolaziš! Onoga dana kad mi se opet pojaviš na oči, zaglavit ćeš!”"},{"v":29,"t":"“Dobro si kazao!” - uzvrati Mojsije. “Lica tvoga više neću vidjeti!”"}]},"11":{"hr":[{"v":1,"t":"“Još ću samo jednom nedaćom udariti faraona i Egipat”, reče Jahve Mojsiju. “Poslije toga pustit će vas odavde. I više: sam će vas odavde potjerati."},{"v":2,"t":"Kaži svijetu neka svaki čovjek ište od svoga susjeda i svaka žena od svoje susjede srebrnih i zlatnih dragocjenosti.”"},{"v":3,"t":"Jahve učini te Egipćani bijahu naklonjeni narodu. Sam Mojsije postane vrlo uvažen u egipatskoj zemlji, u očima faraonovih službenika i u očima naroda."},{"v":4,"t":"A onda Mojsije navijesti: “Ovako poručuje Jahve: 'O ponoći proći ću Egiptom."},{"v":5,"t":"Svaki će prvorođenac u egipatskoj zemlji umrijeti, od prvorođenca faraonova, koji bi imao sjediti na njegovu prijestolju, do prvorođenca ropkinje koja se nalazi uz mlinski kamen; a uginut će i sve prvine od stoke."},{"v":6,"t":"U svoj će zemlji egipatskoj nastati veliki jauk, kakva nije bilo niti će kad poslije biti."},{"v":7,"t":"Među Izraelcima ni pas neće zalajati na živo stvorenje: ni na čovjeka ni na životinju.' Po tome ćete znati da Jahve luči Izraelca od Egipćanina."},{"v":8,"t":"Onda će svi ovi tvoji dvorani k meni doći, preda me se baciti i vikati: Nosi se i ti i sav puk koji za tobom ide! Poslije toga ću otići.” I gnjevan ode od faraona."},{"v":9,"t":"“Neće vas faraon poslušati”, reče Jahve Mojsiju, “a to da bi se umnožila moja znamenja u zemlji egipatskoj.”"},{"v":10,"t":"Mojsije i Aron izveli su sva ta znamenja pred faraonom, ali je Jahve okorio srce faraonu, tako te on nije puštao Izraelaca da odu iz njegove zemlje."}]},"12":{"hr":[{"v":1,"t":"Jahve reče Mojsiju i Aronu u zemlji egipatskoj:"},{"v":2,"t":"“Ovaj mjesec neka vam bude početak mjesecima; neka vam bude prvi mjesec u godini."},{"v":3,"t":"Ovo objavite svoj zajednici izraelskoj: Desetog dana ovoga mjeseca neka svatko za obitelj pribavi jedno živinče. Tako, jedno na obitelj."},{"v":4,"t":"Ako je obitelj premalena da ga potroši, neka se ona priključi svome susjedu, najbližoj kući, prema broju osoba. Podijelite živinče prema tome koliko koja osoba može pojesti."},{"v":5,"t":"Živinče neka bude bez mane, od jedne godine i muško. Možete izabrati bilo janje bilo kozle."},{"v":6,"t":"Čuvajte ga do četrnaestoga dana ovoga mjeseca. A onda neka ga sva izraelska zajednica zakolje kad se spusti suton."},{"v":7,"t":"Neka uzmu krvi i poškrope oba dovratnika i nadvratnik kuće u kojoj se bude blagovalo."},{"v":8,"t":"Meso, pečeno na vatri, neka se pojede te iste noći sa beskvasnim kruhom i gorkim zeljem."},{"v":9,"t":"Da ništa sirovo ili na vodi skuhano od njega niste jeli, nego na vatri pečeno: s glavom, nogama i ponutricom."},{"v":10,"t":"Ništa od njega ne smijete ostaviti za sutradan: što bi god do jutra ostalo, morate na vatri spaliti."},{"v":11,"t":"A ovako ga blagujte: opasanih bokova, s obućom na nogama i sa štapom u ruci. Jedite ga žurno: to je Jahvina pasha."},{"v":12,"t":"Te ću, naime, noći ja proći egipatskom zemljom i pobiti sve prvorođence u zemlji egipatskoj - i čovjeka i životinju. Ja, Jahve, kaznit ću i sva egipatska božanstva."},{"v":13,"t":"Krv neka označuje kuće u kojima vi budete. Gdje god spazim krv, proći ću vas; tako ćete vi izbjeći biču zatornomu kad se oborim na zemlju egipatsku.”"},{"v":14,"t":"“Taj dan neka vam bude spomen-dan. Slavite ga kao blagdan u čast Jahvi. Svetkujte ga po trajnoj uredbi od koljena do koljena."},{"v":15,"t":"Sedam dana jedite beskvasan kruh. Prvoga već dana uklonite kvasac iz svojih kuća. Jer, tko bi god od prvoga do sedmoga dana jeo ukvasan kruh, taj se ima iskorijeniti između Izraelaca."},{"v":16,"t":"Prvoga dana držite sveto zborovanje, a tako i sedmoga dana. Nikakva posla tih dana nemojte raditi. Jedino jelo, što kome treba, možete pripraviti."},{"v":17,"t":"Držite blagdan beskvasnog kruha! Toga sam, naime, dana izveo vaše čete iz zemlje egipatske. Držite zato taj dan kao blagdan od koljena do koljena: to je vječna naredba."},{"v":18,"t":"Od večeri četrnaestoga dana prvoga mjeseca pa do večeri dvadeset prvoga dana toga mjeseca jedite beskvasan kruh."},{"v":19,"t":"Sedam dana ne smije biti kvasca u vašim domovima. Tko bi god jeo bilo što ukvasano, taj neka se ukloni iz izraelske zajednice, bio stranac ili domorodac."},{"v":20,"t":"Ništa ukvasano ne smijete jesti: u svim svojim prebivalištima jedite nekvasan kruh.”"},{"v":21,"t":"Zatim sazva Mojsije sve starješine Izraelaca te im reče: “Idite i pribavite janje za svoje obitelji i žrtvujte Pashu."},{"v":22,"t":"Onda uzmite kitu izopa, zamočite je u krv što je u zdjeli i poškropite krvlju iz zdjele nadvratnik i oba dovratnika. Neka nitko ne izlazi preko kućnih vrata do jutra."},{"v":23,"t":"Kad Jahve bude prolazio da pobije Egipćane, zapazit će krv na nadvratniku i na oba dovratnika, pa će mimoići ta vrata i neće dopustiti da Zatornik uđe u vaše kuće da hara."},{"v":24,"t":"Ovu uredbu držite u svim vremenima kao zakon za se i djecu svoju."},{"v":25,"t":"I kad dođete u zemlju koju će vam Jahve dati kako je obećao, vršite ovaj obred."},{"v":26,"t":"Kad vas vaša djeca zapitaju: Što vam taj obred označuje?"},{"v":27,"t":"odgovorite im: Ovo je pashalna žrtva u čast Jahvi koji je prolazio mimo kuće Izraelaca kad je usmrćivao Egipćane, a naše kuće pošteđivao.” Tada narod popada ničice i pokloni se."},{"v":28,"t":"Potom Izraelci odu i poslušaju: kako je Jahve Mojsiju i Aronu naredio, tako i učine."},{"v":29,"t":"U ponoći Jahve pobije sve prvorođence po zemlji egipatskoj: od prvorođenca faraonova, koji je imao sjediti na prijestolju, do prvorođenca sužnja u tamnici, a tako i sve prvine od stoke."},{"v":30,"t":"Noću ustane faraon, on pa svi njegovi dvorani i svi Egipćani, jer se strašan jauk razlijegao Egiptom: ne bijaše kuće u kojoj nije ležao mrtvac."},{"v":31,"t":"Faraon pozva u noći Mojsija i Arona te im reče: “Ustajte i odlazite od moga naroda i vi i vaši Izraelci! Idite! Odajte štovanje Jahvi, kako ste tražili."},{"v":32,"t":"Pokupite svoju i sitnu i krupnu stoku, kako ste zahtijevali: idite pa i mene blagoslovite!”"},{"v":33,"t":"Egipćani nagonili narod da brže ide iz zemlje, “jer izgibosmo svi”, govorahu oni."},{"v":34,"t":"Tako narod ponese svoje još neukislo tijesto; naćve, uvijene u ogrtače, ponesoše na ramenima."},{"v":35,"t":"I učiniše Izraelci kako im je Mojsije bio rekao: zatražiše od Egipćana srebrnine, i zlatnine, i odjeće."},{"v":36,"t":"Jahve je učinio te Egipćani bijahu naklonjeni narodu pa davahu. Tako su Egipćane oplijenili."},{"v":37,"t":"Pođu tako Izraelci iz Ramsesa prema Sukotu. Bilo je oko šest stotina tisuća pješaka, osim žena i djece."},{"v":38,"t":"A mnogo i drugoga svijeta pođe s njima, i mnoga stoka, krupna i sitna."},{"v":39,"t":"Ispeku beskvasne prevrte od tijesta što su ga iz Egipta ponijeli: nije se bilo ukvasalo. A kako su bili tjerani iz Egipta, nisu mogli odgađati, i tako nisu sebi spremili poputninu."},{"v":40,"t":"Vrijeme što su ga Izraelci proveli u Egiptu iznosilo je četiri stotine i trideset godina."},{"v":41,"t":"I kad se navrši četiri stotine i trideset godina - točno onoga dana - sve čete Jahvine iziđoše iz zemlje egipatske."},{"v":42,"t":"Ona noć koju je Jahve probdio da njih izbavi iz Egipta, odonda je svima Izraelcima, u sve naraštaje njihove, noć bdjenja u čast Jahvi."},{"v":43,"t":"Reče Jahve Mojsiju i Aronu: “Neka je ovo pravilo za pashalnu žrtvu: ni jedan stranac ne smije od nje jesti!"},{"v":44,"t":"Svaki rob, kupljen novcem i obrezan, može je jesti."},{"v":45,"t":"Ni gost ni najamnik ne smiju je jesti!"},{"v":46,"t":"Blagujte je u jednoj te istoj kući; iz kuće ne smijete iznositi mesa niti na žrtvi smijete koju kost slomiti."},{"v":47,"t":"Sva zajednica Izraelaca neka je prikazuje!"},{"v":48,"t":"Ako bi stranac koji među vama boravi htio svetkovati Pashu u čast Jahvi, svi se njegovi muški moraju obrezati. Tek tada neka pristupi i slavi je, jer je tada kao i domorodac zemlje. Ali neobrezani ne smije od nje jesti."},{"v":49,"t":"Neka vrijedi isto pravilo za domoroca i pridošlicu koji među vama boravi.”"},{"v":50,"t":"Svi Izraelci poslušaju: kako je Jahve naredio Mojsiju i Aronu, tako su i učinili."},{"v":51,"t":"Toga istog dana izbavio je Jahve Izraelce u njihovim četama iz zemlje egipatske."}]},"13":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Meni posvetite svakoga prvorođenca! Prvenci materina krila kod Izraelaca, i od ljudi i od životinja, meni pripadaju!”"},{"v":3,"t":"A onda Mojsije reče narodu: “Sjećajte se ovoga dana u koji ste izbavljeni iz Egipta, iz kuće ropstva, jer vas Jahve izbavi odande svojom jakom mišicom. Ukvasani kruh neka se ne jede!"},{"v":4,"t":"Ovoga dana mjeseca Abiba vaše je izbavljenje."},{"v":5,"t":"Stoga: kad te Jahve uvede u zemlju Kanaanaca, Hetita, Amorejaca, Hivijaca i Jebusejaca, za koju se zakleo tvojim precima da će ti je dati - zemlju kojom teče med i mlijeko - ovoga mjeseca obavi ovakav obred:"},{"v":6,"t":"sedam dana jedi nekvasan kruh, a sedmoga dana neka se slavi svetkovina u čast Jahvi."},{"v":7,"t":"Sedam dana neka se jede nekvasan kruh; ukvasanog kruha neka ne bude kod tebe; i neka se nigdje ne vidi kvasac na tvome području."},{"v":8,"t":"Svome sinu toga dana objasni: to je za ono što mi je Jahve učinio kad sam se iz Egipta izbavio."},{"v":9,"t":"Neka ti bude kao znak na tvojoj ruci i kao opomena na tvome čelu: da Jahvin zakon bude uvijek na tvojim ustima. Jer te rukom jakom Jahve izbavio iz Egipta."},{"v":10,"t":"Ovaj propis vršite svake godine u određeno vrijeme.”"},{"v":11,"t":"“A kada te Jahve dovede u zemlju Kanaanaca - kako vam se zakle, tebi i tvojim ocima - i kada ti je preda,"},{"v":12,"t":"ustupajte Jahvi prvorođence materinjega krila, a tako i sve prvine što ih tvoja stoka dade - svako muško pripada Jahvi!"},{"v":13,"t":"Svaku prvinu magaradi otkupi janjetom ili jaretom. Ako je ne otkupiš, slomi joj vrat. A svakoga prvorođenca između svoje djece otkupi."},{"v":14,"t":"Kad te sin tvoj sutra zapita: Što znači to? - odgovori mu: Rukom jakom izvede nas Jahve iz Egipta, iz kuće ropstva."},{"v":15,"t":"Kako je faraon postao tvrdokoran pa nas nije htio pustiti, Jahve je poubijao sve prvorođence u zemlji egipatskoj: prvorođence ljudi i prvine stoke. Eto zato Jahvi žrtvujem svaku mušku prvinu materinjega krila, a svakoga prvorođenca od svojih sinova otkupljujem."},{"v":16,"t":"Neka ti to bude kao znak na tvojoj ruci i kao znamenje posred čela da nas je rukom jakom Jahve izbavio iz Egipta.”"},{"v":17,"t":"Kad je faraon dopustio da narod ode, Bog ih nije poveo prema filistejskoj zemlji, iako je onuda bilo najbliže. Bog je, naime, rekao: “Mogao bi se narod predomisliti i vratiti u Egipat kad vidi ratovanje.”"},{"v":18,"t":"Stoga Bog povede narod zaobilaznim putem, kroz pustinju prema Crvenome moru. Izraelci su napustili zemlju egipatsku naoružani od glave do pete."},{"v":19,"t":"Mojsije ponese sa sobom Josipove kosti. Jer Josip bijaše zakleo Izraelce riječima: “Bog će se zacijelo za vas zauzeti. Tada i moje kosti odavde ponesite sa sobom!”"},{"v":20,"t":"Krenuvši iz Sukota, utabore se u Etamu, na kraju pustinje."},{"v":21,"t":"Jahve je išao pred njima, danju u stupu od oblaka da im put pokazuje, a noću u stupu od ognja da im svijetli. Tako su mogli putovati i danju i noću."},{"v":22,"t":"I nije ispred naroda nestajao stup od oblaka danju ni stup od ognja noću."}]},"14":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Reci Izraelcima da se vrate i utabore pred Pi-Hahirotom, između Migdola i mora, nasuprot Baal-Sefonu. Utaborite se nasuprot ovome mjestu, uz more."},{"v":3,"t":"Faraon će reći: 'Izraelci lutaju krajem tamo-amo; pustinja ih zatvorila.'"},{"v":4,"t":"Ja ću otvrdnuti faraonu srce, i on će za njima poći u potjeru. Ali ja ću se proslaviti nad faraonom i svom njegovom vojskom. Tako će Egipćani spoznati da sam ja Jahve.” Izraelci tako učine."},{"v":5,"t":"Kad su egipatskom kralju kazali da je narod pobjegao, faraon i njegovi dvorani predomisliše se o narodu. “Što ovo učinismo!” - rekoše. “Pustismo Izraelce i više nam neće služiti.”"},{"v":6,"t":"Zato opremi faraon svoja kola i povede svoju vojsku."},{"v":7,"t":"Uze šest stotina svojih kola sve poizbor i ostala kola po Egiptu. I u svima bijahu štitonoše."},{"v":8,"t":"Jahve otvrdnu srce faraonu, kralju egipatskom, te on krenu u potjeru za Izraelcima, koji su otišli uzdignute pesnice."},{"v":9,"t":"Egipćani, dakle, pođu za njima u potjeru. I dok su Izraelci taborovali uz more, blizu Pi-Hahirota nasuprot Baal-Sefonu, stignu ih svi faraonovi konji pod kolima, njegovi konjanici i njegovi ratnici."},{"v":10,"t":"Kako se faraon približavao, Izraelci pogledaju i opaze da su Egipćani za njima u potjeri, pa ih obuzme velik strah. I poviču Izraelci Jahvi:"},{"v":11,"t":"“Zar nije bilo grobova u Egiptu”, reknu Mojsiju, “pa si nas izveo da pomremo u pustinji? Kakvu si nam uslugu učinio što si nas izveo iz Egipta!"},{"v":12,"t":"Zar ti nismo rekli baš ovo u Egiptu: Pusti nas! Služit ćemo Egipćane! Bolje nam je i njih služiti nego u pustinji poginuti.”"},{"v":13,"t":"“Ne bojte se!” - reče Mojsije narodu. “Stojte čvrsto pa ćete vidjeti što će vam Jahve učiniti da vas danas spasi: Egipćane koje danas vidite nikad više nećete vidjeti."},{"v":14,"t":"Jahve će se boriti za vas. Budite mirni!”"},{"v":15,"t":"“Zašto zapomažete prema meni?” - reče Jahve Mojsiju. “Reci Izraelcima da krenu na put."},{"v":16,"t":"A ti podigni svoj štap, ispruži svoju ruku nad morem i razdijeli ga nadvoje da Izraelci mogu proći posred mora po suhu."},{"v":17,"t":"Ja ću otvrdnuti srce Egipćana, i oni će poći za njima, a ja ću se onda proslaviti nad faraonom i njegovim ratnicima, njegovim kolima i konjanicima."},{"v":18,"t":"Neka znaju Egipćani da sam ja Jahve kad se proslavim nad faraonom, njegovim kolima i njegovim konjanicima.”"},{"v":19,"t":"Anđeo Božji, koji je išao na čelu izraelskih četa, promijeni mjesto i stupi im za leđa. A i stup od oblaka pomakne se ispred njih i stade im za leđa."},{"v":20,"t":"Smjesti se između vojske egipatske i vojske izraelske te postade onima oblak taman, a ovima rasvjetljivaše noć, tako te ne mogoše jedni drugima prići cijele noći."},{"v":21,"t":"Mojsije je držao ruku ispruženu nad morem dok je Jahve svu noć na stranu valjao vode jakim istočnim vjetrom i more posušio. Kad su se vode razdvojile,"},{"v":22,"t":"Izraelci siđoše u more na osušeno dno, a vode stajahu kao bedem njima nadesno i nalijevo."},{"v":23,"t":"Egipćani: svi faraonovi konji, kola i konjanici, nagnu za njima u more, u potjeru."},{"v":24,"t":"Za jutarnje straže pogleda Jahve iz stupa od ognja i oblaka na egipatsku vojsku i u njoj stvori zbrku."},{"v":25,"t":"Zakoči točkove njihovih kola da su se jedva naprijed micali. “Bježimo od Izraelaca!” - poviču Egipćani, “jer Jahve se za njih bori protiv Egipćana!” Tada će Jahve Mojsiju:"},{"v":26,"t":"“Pruži ruku nad more da se vode vrate na Egipćane, na njihova kola i konjanike.”"},{"v":27,"t":"Mojsije pruži ruku nad more i u cik zore more se vrati u svoje korito. Kako su Egipćani, bježeći, jurili prema moru, Jahve ih strmoglavi usred voda."},{"v":28,"t":"Tako vode, slijevajući se natrag, potope kola, konjanike i svu vojsku faraonovu koja bijaše pošla u potjeru za Izraelcima - u more. I ne ostade od njih ni jedan jedini."},{"v":29,"t":"A Izraelci išli suhim posred mora, vode im stale kao zid zdesna i slijeva."},{"v":30,"t":"Tako Jahve u onaj dan izbavi Izraela iz šaka egipatskih, i vidje Izrael pomorene Egipćane na morskome žalu."},{"v":31,"t":"Osvjedoči se Izrael i o silnoj moći koju Jahve pokaza nad Egipćanima. Narod se poboja Jahve i povjerova Jahvi i njegovu sluzi Mojsiju."}]},"15":{"hr":[{"v":1,"t":"Tada Mojsije s Izraelcima zapjeva ovu pjesmu Jahvi u slavu: “U čast Jahvi zapjevat ću, jer se slavom proslavio! Konja s konjanikom u more je survao."},{"v":2,"t":"Moja je snaga, moja pjesma - Jahve jer je mojim postao izbaviteljem. On je Bog moj, njega ja ću slaviti, on je Bog oca moga, njega ću veličati."},{"v":3,"t":"Jahve je ratnik hrabar, Jahve je ime njegovo."},{"v":4,"t":"Kola faraonova i vojsku mu u more baci; cvijet njegovih štitonoša More crveno proguta."},{"v":5,"t":"Valovi ih prekriše; poput kamena u morske potonuše dubine."},{"v":6,"t":"Desnica tvoja, Jahve, snagom se prodiči; desnica tvoja, Jahve, raskomada dušmana."},{"v":7,"t":"Veličanstvom svojim obaraš ti protivnike; puštaš svoj gnjev i on ih k'o slamu proždire."},{"v":8,"t":"Od daha iz tvojih nosnica vode narastoše, valovi se u bedem uzdigoše, u srcu mora dubine se stvrdnuše."},{"v":9,"t":"Mislio je neprijatelj: 'Gonit ću ih, stići, plijen ću podijelit', duša će moja sita ga biti; trgnut ću mač, uništit' ih rukom svojom.'"},{"v":10,"t":"A ti dahom svojim dahnu, more se nad njima sklopi; k'o olovo potonuše silnoj vodi u bezdane."},{"v":11,"t":"Tko je kao ti, Jahve među bogovima, tko kao ti sija u svetosti, u djelima strašan, divan u čudima?"},{"v":12,"t":"Desnicu si pružio i zemlja ih proguta!"},{"v":13,"t":"Milošću svojom vodio si ovaj narod, tobom otkupljen, k svetom tvom Stanu snagom si ga svojom upravio."},{"v":14,"t":"Kada to čuše, prodrhtaše narodi; Filistejce muke spopadoše."},{"v":15,"t":"Užas je srvao edomske glavare, trepet je obuzeo moapske knezove i tresu se svi koji žive u Kanaanu."},{"v":16,"t":"Strah i prepast na njih se obaraju; snaga tvoje ruke skamenila ih je dok narod tvoj, Jahve, ne prođe, dok ne prođe narod tvoj koji si otkupio."},{"v":17,"t":"Dovest ćeš ih i posaditi na gori svoje baštine, na mjestu koje ti, Jahve, svojim učini Boravištem, Svetištem, o Jahve, tvojom rukom sazidanim."},{"v":18,"t":"Vazda i dovijeka Jahve će kraljevati.”"},{"v":19,"t":"Kad su faraonovi konji, njegova kola i konjanici sašli u more, Jahve je na njih povratio morske vode pošto su Izraelci prošli posred mora po suhu."},{"v":20,"t":"Tada Aronova sestra, proročica Mirjam, uze bubanj u ruku, a sve žene pridruže joj se s bubnjem u ruci i plešući."},{"v":21,"t":"Mirjam je začinjala pjesmu: “Zapjevajte Jahvi jer se slavom proslavio! Konja s konjanikom u more je survao.”"},{"v":22,"t":"Pokrene Mojsije Izraelce od Crvenog mora i pođu na put kroz pustinju Šur. Tri su dana putovali pustinjom, a vode nisu našli."},{"v":23,"t":"Dođu k Mari, ali nisu mogli piti vode kod Mare jer je bila gorka. Stoga se i zove Mara."},{"v":24,"t":"Narod je mrmljao na Mojsija i govorio: “Što ćemo piti?”"},{"v":25,"t":"A on zazva Jahvu. Jahve mu pokaže neko drvo. Baci on to drvo u vodu i voda postane slatka. Tu im Jahve postavi zakon i pravo i tu ih stavi u kušnju."},{"v":26,"t":"Zatim reče: “Budeš li zdušno slušao glas Jahve, Boga svoga, vršeći što je pravo u njegovim očima; budeš li pružao svoje uho njegovim zapovijedima i držao njegove zakone, nikakvih bolesti koje sam pustio na Egipćane na vas neću puštati. Jer ja sam Jahve koji dajem zdravlje.”"},{"v":27,"t":"Zatim stignu u Elim, gdje je bilo dvanaest izvora i sedamdeset palma. Tu se, uz vodu, utabore."}]},"16":{"hr":[{"v":1,"t":"Potom krenu iz Elima, i sva izraelska zajednica dođe u pustinju Sin, koja je između Elima i Sinaja, petnaestoga dana drugoga mjeseca nakon odlaska iz zemlje egipatske."},{"v":2,"t":"U pustinji sva izraelska zajednica počne mrmljati protiv Mojsija i Arona."},{"v":3,"t":"“Oh, da smo pomrli od ruke Jahvine u zemlji egipatskoj kad smo sjedili kod lonaca s mesom i jeli kruha do mile volje!” - rekoše im. “Izveli ste nas u ovu pustinju da sve ovo mnoštvo gladom pomorite!”"},{"v":4,"t":"Tada reče Jahve Mojsiju: “Učinit ću da vam daždi kruh s neba. Neka narod ide i skuplja svaki dan koliko mu za dan treba. Tako ću ih kušati i vidjeti hoće li se držati moga zakona ili neće."},{"v":5,"t":"A šestoga dana, kad spreme što su nakupili, bit će dvaput onoliko koliko su skupljali za svaki dan.”"},{"v":6,"t":"Onda Mojsije i Aron progovore svim Izraelcima: “Večeras ćete poznati da vas je Jahve izveo iz zemlje egipatske,"},{"v":7,"t":"a ujutro ćete vidjeti svojim očima Jahvinu slavu, jer vas je čuo Jahve kako ste protiv njega mrmljali. Što smo mi da protiv nas mrmljate?"},{"v":8,"t":"Večeras će vam Jahve dati mesa da jedete”, nastavi Mojsije, “a ujutro kruha do mile volje, jer je Jahve čuo vaše mrmljanje protiv njega. Što smo mi? Vi ne mrmljate protiv nas nego protiv Jahve.”"},{"v":9,"t":"Poslije toga rekne Mojsije Aronu: “Reci svoj izraelskoj zajednici: 'Skupite se pred Jahvu, jer je čuo vaše mrmljanje!'”"},{"v":10,"t":"I dok je Aron svoj izraelskoj zajednici govorio, oni se okrenu prema pustinji, i gle! u oblaku pojavi se Jahvina slava."},{"v":11,"t":"Onda se Jahve oglasi Mojsiju i reče mu:"},{"v":12,"t":"“Čuo sam mrmljanje Izraelaca. Ovako im reci: 'Večeras ćete jesti meso, a ujutro ćete se nasititi kruha. Tada ćete poznati da sam ja Jahve, Bog vaš.'”"},{"v":13,"t":"I doista! Navečer se pojave prepelice i prekriju tabor. A ujutro obilna rosa sve orosila oko tabora."},{"v":14,"t":"Kad se prevlaka rose digla, površinom pustinje ležao tanak sloj, nešto poput pahuljica, kao da se slana uhvatila po zemlji."},{"v":15,"t":"Kad su Izraelci to vidjeli, pitali su jedan drugoga: “Što je to?” Jer nisu znali što je. Onda im Mojsije reče: “To je kruh koji vam je Jahve pribavio za hranu."},{"v":16,"t":"A ovo je zapovijed koju je Jahve izdao: 'Nakupite koliko kome treba za jelo - jedan gomer po osobi, svatko prema broju članova koji su mu u šatoru.'”"},{"v":17,"t":"Izraelci tako uradiše. Neki nakupe više, neki manje."},{"v":18,"t":"Kad su izmjerili na gomer, pokaza se da nije ništa preteklo onome koji bijaše nakupio mnogo, a niti je nedostajalo onome koji bijaše nakupio manje: svatko je nakupio koliko mu je trebalo za jelo."},{"v":19,"t":"“Neka nitko ne ostavlja ništa za ujutro!” - rekne im Mojsije."},{"v":20,"t":"Ali oni nisu poslušali Mojsija; neki ostave i za sutra. A to im se ucrva i usmrdje. Mojsije se na njih razljuti."},{"v":21,"t":"Tako su skupljali svako jutro koliko je kome trebalo za jelo. I kad bi sunce ogrijalo, mÓana bi se rastopila."},{"v":22,"t":"Onda šestoga dana nakupiše dvostruku količinu hrane - po dva gomera na svakoga. Kad su starješine zajednice došle da izvijeste Mojsija,"},{"v":23,"t":"on im reče: “Ovo je zapovijed Jahvina: Sutra je dan potpunog odmora, subota Jahvi posvećena. Ispecite što želite peći; skuhajte što želite kuhati. Sve što vam preteče ostavite za sutra.”"},{"v":24,"t":"Ostave to oni za sutra, kako je Mojsije naredio, i niti se usmrdjelo niti su se crvi pojavili."},{"v":25,"t":"“Jedite to danas”, reče im Mojsije, “jer je ovaj dan subota u čast Jahve; danas nećete naći mÓane na polju."},{"v":26,"t":"Šest je dana skupljajte, a sedmoga, u subotu, neće je biti.”"},{"v":27,"t":"Bijaše nekih koji su i sedmoga dana išli da je nakupe, ali ništa ne nađoše."},{"v":28,"t":"Zato Jahve reče Mojsiju: “Dokle ćete odbijati da se pokorite mojim zapovijedima i mojim zakonima?"},{"v":29,"t":"Pogledajte! Zato što vam je Jahve dao subotu, daje vam hrane šestoga dana za dva dana. Neka svatko stoji gdje jest; neka nitko u sedmi dan ne izlazi iz svoga stana.”"},{"v":30,"t":"Tako se sedmoga dana narod odmarao."},{"v":31,"t":"Dom je Izraelov tu hranu prozvao mÓanom. Bijaše kao zrno korijandra; bijela, a imala je ukus medenog kolačića."},{"v":32,"t":"Onda rekne Mojsije: “Ovo je zapovijed koju je izdao Jahve: Napunite tim jedan gomer i čuvajte ga za svoje potomke da vide hranu kojom sam vas hranio u pustinji kad sam vas izbavio iz zemlje egipatske.”"},{"v":33,"t":"I naredi Mojsije Aronu: “Uzmi jednu posudu; stavi u nju cio gomer mane, a onda je položi pred Jahvu da se sačuva za vaše potomke.”"},{"v":34,"t":"Kako je Jahve naredio Mojsiju, Aron je stavi pred Svjedočanstvo na čuvanje."},{"v":35,"t":"Izraelci su se hranili manom četrdeset godina, sve dok nisu došli u naseljenu zemlju: jeli su manu do dolaska na granicu zemlje kanaanske."},{"v":36,"t":"Gomer je deseti dio efe."}]},"17":{"hr":[{"v":1,"t":"Sva izraelska zajednica po Jahvinoj zapovijedi krene dalje iz pustinje Sina. Utabore se kod Refidima. Tu nije bilo vode da narod pije."},{"v":2,"t":"Zato narod zapodjene prepirku s Mojsijem. Vikali su: “Daj nam vode da pijemo!” A Mojsije im odgovori: “Zašto se sa mnom prepirete? Zašto kušate Jahvu?”"},{"v":3,"t":"Ali je narod žeđao za vodom, pa je mrmljao na Mojsija i govorio: “Zašto si nas iz Egipta izveo? Zar da nas žeđom pomoriš, nas, našu djecu i našu stoku?”"},{"v":4,"t":"“Što ću s ovim narodom!” - zazivao je Mojsije Jahvu. “Još malo pa će me kamenovati.”"},{"v":5,"t":"“Istupi pred narod!” - rekne Jahve Mojsiju. “Uzmi sa sobom nekoliko izraelskih starješina; uzmi u ruku štap kojim si udario Rijeku i pođi."},{"v":6,"t":"A ja ću stajati pred tobom ondje, na pećini na Horebu. Udari po pećini: iz nje će poteći voda, pa neka se narod napije.” Mojsije učini tako naočigled izraelskih starješina."},{"v":7,"t":"Mjesto prozovu Masa i Meriba, zbog toga što su se Izraelci prepirali i kušali Jahvu govoreći: “Je li Jahve među nama ili nije?”"},{"v":8,"t":"Uto dođu Amalečani i zarate s Izraelcima kod Refidima."},{"v":9,"t":"A Mojsije reče Jošui: “Odaberi momčad pa pođi i zapodjeni borbu s Amalečanima. Ja ću sutra stati na vrh brda, sa štapom Božjim u ruci.”"},{"v":10,"t":"Jošua učini kako mu je Mojsije rekao te zađe u borbu s Amalečanima, a Mojsije, Aron i Hur uzađoše na vrh brda."},{"v":11,"t":"I dok bi Mojsije držao ruke uzdignute, Izraelci bi nadjačavali; a kad bi ruke spustio, nadjačavali bi Amalečani."},{"v":12,"t":"Ali Mojsiju ruke napokon klonu. Zato uzeše kamen, staviše ga poda nj i on sjede, dok mu Aron i Hur, jedan s jedne, a drugi s druge strane, držahu ruke, tako da mu izdržaše do sunčanog zalaska."},{"v":13,"t":"I Jošua oštricom mača svlada Amaleka i njegov narod."},{"v":14,"t":"Onda Jahve reče Mojsiju: “Zapiši ovo u knjigu na sjećanje i utuvi u uši Jošui da ću ja spomen na Amalečane sasvim izbrisati pod nebom!”"},{"v":15,"t":"Podiže zatim Mojsije žrtvenik i nazva ga : Jahve mi je stijeg!"},{"v":16,"t":"“Jer”, reče, “Jahvin stijeg u ruku! Jahvin je boj protiv Amalečana od naraštaja do naraštaja!”"}]},"18":{"hr":[{"v":1,"t":"A Jitro, midjanski svećenik, tast Mojsijev, ču sve što učini Bog Mojsiju i svemu izraelskom narodu i kako Jahve izbavi Izraelce iz Egipta."},{"v":2,"t":"Tada tast Mojsijev Jitro povede Siporu, Mojsijevu ženu - koju Mojsije bijaše otpustio -"},{"v":3,"t":"i oba njezina sina. Jednomu je bilo ime Geršon, a to će reći: “Bijah došljak u tuđoj zemlji.”"},{"v":4,"t":"Drugi se zvao Eliezer, to jest: “Bog oca moga bio mi je u pomoći i spasio me od faraonova mača.”"},{"v":5,"t":"Tako Mojsijev tast Jitro povede k Mojsiju u pustinju, gdje se Mojsije bio utaborio na Božjem brdu, njegove sinove i njegovu ženu."},{"v":6,"t":"Poruči on Mojsiju: “Ja, tvoj tast Jitro, dolazim k tebi s tvojom ženom i s oba njezina sina.”"},{"v":7,"t":"Izađe Mojsije u susret svome tastu; duboko mu se nakloni i zagrli ga. Pošto su se upitali za zdravlje, uđu pod šator."},{"v":8,"t":"Mojsije je onda pripovijedao svome tastu o svemu što je Jahve učinio faraonu i Egipćanima zbog Izraelaca; o svim nezgodama što su ih snašle na putu, ali ih je Jahve od njih izbavio."},{"v":9,"t":"Jitro se radovao svemu dobru koje je Jahve učinio Izraelcima i što ih je oslobodio od egipatskih šaka."},{"v":10,"t":"“Neka je hvaljen Jahve koji vas je izbavio od egipatskih šaka i od šaka faraonovih”, reče Jitro."},{"v":11,"t":"“Sada znam da je Jahve veći od svih bogova jer je izbavio narod ispod egipatske vlasti kad su s njim okrutno postupali.”"},{"v":12,"t":"Zatim Jitro, Mojsijev tast, prinese Bogu žrtvu paljenicu i prinos. Uto dođe Aron i sve izraelske starješine da s Mojsijevim tastom blaguju gozbu pred Bogom."},{"v":13,"t":"Sutradan Mojsije sjede da kroji pravdu narodu. Narod je oko njega stajao od jutra do mraka."},{"v":14,"t":"Vidjevši Mojsijev tast sav trud što ga on za narod čini, rekne mu: “Što to imaš toliko s narodom? I zašto ti sam sjediš, a sav narod stoji oko tebe od jutra do mraka?”"},{"v":15,"t":"“Narod dolazi k meni”, odgovori Mojsije, “da se s Bogom posavjetuje."},{"v":16,"t":"Kad zađu u prepirku, dođu k meni. Ja onda rasudim između jednoga i drugoga; izložim im Božje zakone i odredbe.”"},{"v":17,"t":"“Nije dobro kako radiš”, odgovori Mojsiju tast."},{"v":18,"t":"“I ti i taj narod s tobom potpuno ćete se iscrpsti. Taj je posao za te pretežak; sam ga ne možeš obavljati."},{"v":19,"t":"Poslušaj me. Svjetovat ću te, i Bog će biti s tobom! Ti zastupaj narod pred Bogom; podastiri Bogu njihove razmirice."},{"v":20,"t":"Poučavaj ih o zakonima i odredbama; svraćaj ih na put kojim moraju ići, upućuj ih na djela koja moraju vršiti."},{"v":21,"t":"Onda proberi između svega puka ljude sposobne, bogobojazne i pouzdane, koji mrze mito, te ih postavi za glavare puku: tisućnike, stotnike, pedesetnike i desetnike."},{"v":22,"t":"Neka sude narodu u svako doba. Sve veće slučajeve neka preda te iznose, a u manjima neka sami rasuđuju. Olakšaj sebi breme: neka ga oni s tobom nose."},{"v":23,"t":"Ako tako uradiš - i Bog ti to odobri - moći ćeš izdržati, a sav ovaj narod odlazit će kući u miru.”"},{"v":24,"t":"Mojsije posluša savjet svoga tasta i učini sve kako ga svjetova."},{"v":25,"t":"Probere Mojsije sposobnih ljudi od svih Izraelaca pa ih postavi za glavare narodu: tisućnike, stotnike, pedesetnike i desetnike."},{"v":26,"t":"Oni su sudili narodu u svako doba. Teže slučajeve iznosili bi Mojsiju, a sve manje rješavali sami."},{"v":27,"t":"Zatim Mojsije otpusti svoga tasta i on ode u svoju zemlju."}]},"19":{"hr":[{"v":1,"t":"Tri mjeseca nakon izlaska iz zemlje egipatske, istoga dana, stignu Izraelci u Sinajsku pustinju."},{"v":2,"t":"Idući od Refidima, dođu u Sinajsku pustinju i utabore se u pustinji. Postave Izraelci tabor tu pred brdom,"},{"v":3,"t":"a Mojsije se popne k Bogu. Jahve ga zovne s brda pa mu rekne: “Ovako kaži domu Jakovljevu, proglasi djeci Izraelovoj:"},{"v":4,"t":"'Vi ste vidjeli što sam učinio Egipćanima; kako sam vas nosio na orlovskim krilima i k sebi vas doveo."},{"v":5,"t":"Stoga, budete li mi se vjerno pokoravali i držali moj Savez, vi ćete mi biti predraga svojina mimo sve narode - tÓa moj je sav svijet! -"},{"v":6,"t":"vi ćete mi biti kraljevstvo svećenika, narod svet.' Tim riječima oslovi Izraelce.”"},{"v":7,"t":"Mojsije se vrati i sazva narodne starješine te im izloži sve što mu je Jahve naredio."},{"v":8,"t":"A sav narod uzvrati jednoglasno: “Vršit ćemo sve što je Jahve naredio.” Onda Mojsije prenese odgovor naroda Jahvi."},{"v":9,"t":"Nato Jahve reče Mojsiju: “Ja ću, evo, doći k tebi u gustom oblaku da narod čuje kad budem s tobom govorio i da ti zauvijek vjeruje.” Tako je Mojsije prenio Jahvi odgovor naroda."},{"v":10,"t":"“Pođi k narodu”, reče Jahve Mojsiju, “i posvećuj ga danas i sutra. Neka opere svoju odjeću;"},{"v":11,"t":"neka bude gotov prekosutra, jer će prekosutra sići Jahve na brdo Sinaj naočigled svega puka."},{"v":12,"t":"Postavi naokolo granicu za narod i izdaj naredbu: 'Pripazite da se na brdo ne penjete; da se ni podnožja ne dotičete! Tko se god brda dotakne, smrt će ga snaći."},{"v":13,"t":"Nikakva ruka neka ga se ne dotakne, nego neka bude kamenjem zasut ili strijelom ustrijeljen: bio čovjek ili živinče, neka na životu ne ostane.' Na otegnuti zvuk trube neka se na brdo penju.”"},{"v":14,"t":"Mojsije siđe s brda k narodu i poče posvećivati narod. Oni operu svoju odjeću."},{"v":15,"t":"“Budite gotovi za prekosutra!” - rekne Mojsije narodu. “Ne primičite se ženi!”"},{"v":16,"t":"A prekosutra, u osvit dana, prolomi se grmljavina, munje zasijevaše, a gust se oblak nadvi nad brdo. Gromko zaječa truba, zadrhta sav puk koji bijaše u taboru."},{"v":17,"t":"Mojsije povede puk iz tabora u susret Bogu. Stadoše na podnožju brda."},{"v":18,"t":"Brdo Sinaj zavilo se u dim jer je Jahve u obliku ognja sišao na nj. Dizao se dim kao dim iz peći. Sve se brdo silno treslo."},{"v":19,"t":"Zvuk trube bivao sve jači. Mojsije je govorio, a Bog mu grmljavinom odgovarao."},{"v":20,"t":"Jahve siđe na Sinajsko brdo, na vrhunac, i pozva Jahve Mojsija na vrhunac brda. Mojsije se uspe."},{"v":21,"t":"Sad Jahve reče Mojsiju: “Siđi i opomeni narod da ne bi provalio prema Jahvi da ga vidi. Mnogo bi ih poginulo."},{"v":22,"t":"I sami svećenici, koji dolaze blizu Jahvi, moraju se očistiti, da ih Jahve ne uništi.”"},{"v":23,"t":"“Narod se ne može popeti na brdo Sinaj”, odgovori Mojsije Jahvi, “jer si nas sam ti opomenuo: 'Postavi granice naokolo brda i proglasi ga svetim.'”"},{"v":24,"t":"“Siđi pa se opet popni zajedno s Aronom”, odgovori mu Jahve. “Ali neka svećenici i narod ne navaljuju da se popnu prema Jahvi da ne izginu.”"},{"v":25,"t":"Mojsije siđe k narodu i sve mu kaza."}]},"20":{"hr":[{"v":1,"t":"Onda Bog izgovori sve ove riječi:"},{"v":2,"t":"“Ja sam Jahve, Bog tvoj, koji sam te izveo iz zemlje egipatske, iz kuće ropstva."},{"v":3,"t":"Nemoj imati drugih bogova uz mene."},{"v":4,"t":"Ne pravi sebi lika ni obličja bilo čega što je gore na nebu, ili dolje na zemlji, ili u vodama pod zemljom."},{"v":5,"t":"Ne klanjaj im se niti im služi. Jer ja, Jahve, Bog tvoj, Bog sam ljubomoran. Kažnjavam grijeh otaca - onih koji me mrze - na djeci do trećeg i četvrtog koljena,"},{"v":6,"t":"a iskazujem milosrđe tisućama koji me ljube i vrše moje zapovijedi."},{"v":7,"t":"Ne uzimaj uzalud imena Jahve, Boga svoga, jer Jahve ne oprašta onome koji uzalud izgovara ime njegovo."},{"v":8,"t":"Sjeti se da svetkuješ dan subotni."},{"v":9,"t":"Šest dana radi i obavljaj sav svoj posao."},{"v":10,"t":"A sedmoga je dana subota, počinak posvećen Jahvi, Bogu tvojemu. Tada nikakva posla nemoj raditi: ni ti, ni sin tvoj, ni kći tvoja, ni sluga tvoj, ni sluškinja tvoja, ni živina tvoja, niti došljak koji se nađe unutar tvojih vrata."},{"v":11,"t":"Ta i Jahve je šest dana stvarao nebo, zemlju i more i sve što je u njima, a sedmoga je dana počinuo. Stoga je Jahve blagoslovio i posvetio dan subotni."},{"v":12,"t":"Poštuj oca svoga i majku svoju da imadneš dug život na zemlji koju ti da Jahve, Bog tvoj."},{"v":13,"t":"Ne ubij!"},{"v":14,"t":"Ne učini preljuba!"},{"v":15,"t":"Ne ukradi!"},{"v":16,"t":"Ne svjedoči lažno na bližnjega svoga!"},{"v":17,"t":"Ne poželi kuće bližnjega svoga! Ne poželi žene bližnjega svoga; ni sluge njegova, ni sluškinje njegove, ni vola njegova, ni magarca njegova, niti išta što je bližnjega tvoga!”"},{"v":18,"t":"Sav je puk bio svjedok grmljavine i sijevanja, svi čuše zvuk trube i vidješe kako se brdo dimi: gledali su i tresli se i stajali podalje."},{"v":19,"t":"Onda rekoše Mojsiju: “Ti nam govori, a mi ćemo slušati. Neka nam Bog ne govori, da ne pomremo!”"},{"v":20,"t":"“Ne bojte se”, reče Mojsije narodu. “Bog je došao da vas samo iskuša; da strah pred njim ostane s vama te da ne griješite.”"},{"v":21,"t":"Narod ostane podalje, a Mojsije pristupi gustom oblaku gdje se Bog nalazio."},{"v":22,"t":"“Ovako reci Izraelcima”, progovori Jahve Mojsiju. “Sami ste vidjeli da sam s vama govorio s neba."},{"v":23,"t":"Ne pravite uza me kumira od srebra niti sebi pravite kumira od zlata."},{"v":24,"t":"Načini mi žrtvenik od zemlje i na njemu mi prinosi svoje žrtve paljenice i žrtve pričesnice, svoju sitnu i svoju krupnu stoku. Na svakome mjestu koje odredim da se moje ime spominje ja ću doći k tebi da te blagoslovim."},{"v":25,"t":"Ako mi budeš gradio kameni žrtvenik, nemoj ga graditi od klesanoga kamena, jer čim na nj spustiš svoje dlijeto, oskvrnit ćeš ga."},{"v":26,"t":"Ne uzlazi na moj žrtvenik po stepenicama, da se ne pokaže na njemu golotinja tvoja.”"}]},"21":{"hr":[{"v":1,"t":"“Ovo su propisi koje treba da im izložiš:"},{"v":2,"t":"Kad za roba kupiš jednoga Hebreja, neka služi šest godina. Sedme godine neka ode, bez otkupnine, slobodan."},{"v":3,"t":"Ako dođe sam, neka sam i ode; ako li je oženjen, neka s njim ide i njegova žena."},{"v":4,"t":"Ako mu gospodar nabavi ženu, pa mu ona rodi bilo sinova bilo kćeri, i žena i njezina djeca neka pripadnu njezinu gospodaru, a on neka ide sam."},{"v":5,"t":"Ali ako rob otvoreno izjavi: 'Volim svoga gospodara, svoju ženu i svoju djecu, neću da budem slobodan',"},{"v":6,"t":"neka ga onda njegov gospodar dovede k Bogu. Kad ga dovede k vratima ili dovratku, neka mu gospodar šilom probuši uho i neka mu trajno ostane u službi."},{"v":7,"t":"Kad čovjek proda svoju kćer za ropkinju, neka se ona ne oslobađa kao i muški robovi."},{"v":8,"t":"Ako se ne svidi svome gospodaru, koji ju je sebi bio odredio, neka joj dopusti da se otkupi. Nema prava prodati je strancima kad joj nije bio vjeran."},{"v":9,"t":"A ako je odredi svome sinu, neka s njome postupa kao i sa kćeri."},{"v":10,"t":"Ako se oženi drugom, ne smije prvoj uskraćivati hrane, odjeće ili njezinih bračnih prava."},{"v":11,"t":"Ne bude li joj činio ovo troje, neka je slobodna da ode bez otkupnine.”"},{"v":12,"t":"“Tko god udari čovjeka pa ga usmrti, neka se smrću kazni."},{"v":13,"t":"Ali ako to ne učini hotimično, nego Bog pripusti da padne u njegovu šaku, odredit ću ti mjesto kamo može pobjeći."},{"v":14,"t":"Tko hotimično navali na svoga bližnjega te ga podmuklo ubije, odvuci ga i s moga žrtvenika da se pogubi."},{"v":15,"t":"Tko udari svoga oca ili svoju majku, neka se kazni smrću."},{"v":16,"t":"Tko otme čovjeka - bilo da ga proda, bilo da ga u svojoj vlasti zadrži - neka se kazni smrću."},{"v":17,"t":"Tko prokune svoga oca ili svoju majku, neka se kazni smrću.”"},{"v":18,"t":"“Ako se ljudi posvade, pa jedan od njih udari drugoga kamenom ili šakom, ali ovaj ne pogine nego padne u postelju,"},{"v":19,"t":"ali poslije ustane i mogne izlaziti, makar i sa štapom, onda onome koji ga je udario neka je oprošteno, samo neka mu plati njegov gubitak vremena i pribavi mu posvemašnje izlječenje."},{"v":20,"t":"Ako tko udari batinom svoga roba ili svoju ropkinju te umru pod njegovom šakom, mora snositi osvetu."},{"v":21,"t":"Ali ako rob preživi dan-dva, neka se osveta ne provodi, jer je rob njegovo vlasništvo."},{"v":22,"t":"Ako se ljudi pobiju i udare trudnu ženu te ona pobaci, ali druge štete ne bude, onda onaj koji ju je udario neka plati odštetu koju zatraži njezin muž. On neka plati kako suci odrede."},{"v":23,"t":"Bude li drugog zla, neka je kazna: život za život,"},{"v":24,"t":"oko za oko, zub za zub, ruka za ruku, noga za nogu,"},{"v":25,"t":"opeklina za opeklinu, rana za ranu, modrica za modricu."},{"v":26,"t":"Udari li tko svoga roba ili svoju ropkinju u oko i upropasti ga, neka ga oslobodi zbog oka."},{"v":27,"t":"Ako izbije zub svome robu - ili svojoj ropkinji - neka ga oslobodi zbog zuba.”"},{"v":28,"t":"“Kad goveče ubode čovjeka ili ženu pa ih usmrti, neka se kamenjem kamenuje. Njegovo se meso tada ne smije pojesti, a vlasniku njegovu neka je oprošteno."},{"v":29,"t":"Ali ako je to goveče i prije bolo, a njegov vlasnik, iako opominjan, nije ga čuvao, pa ono usmrti čovjeka ili ženu, neka se to goveče kamenuje; a i njegov se vlasnik ima pogubiti."},{"v":30,"t":"Ako se vlasniku označi otkupna cijena da svoj život iskupi, neka plati koliko mu se odredi."},{"v":31,"t":"Ubode li goveče dječaka ili djevojčicu, neka se prema njemu postupi isto prema ovome pravilu."},{"v":32,"t":"Ako ubode roba ili ropkinju, neka vlasnik isplati njihovu gospodaru trideset srebrnih šekela, a goveče neka se kamenuje."},{"v":33,"t":"Kad tko ostavi bunar otvoren, ili tko iskopa bunar a ne pokrije ga, pa u nj upadne goveče ili magare, vlasnik bunara ima dati naknadu:"},{"v":34,"t":"neka isplati vlasniku u novcu, a uginula životinja neka njemu pripadne."},{"v":35,"t":"Kad nečije goveče ubode goveče drugome te ono ugine, onda neka prodaju živo goveče, a dobiveni novac neka podijele; i uginulo goveče neka među sebe podijele."},{"v":36,"t":"Ali ako se zna da je to goveče i prije bolo, a njegov ga gospodar nije čuvao, onda mora nadoknaditi goveče za goveče, dok će uginulo živinče biti njegovo.”"},{"v":37,"t":"“Tko ukrade goveče ili marvinče od sitne stoke, pa bilo da ga zakolje, bilo da ga proda, onda za jedno goveče neka se vrati petero goveda, a za malo marvinče četvero marvinčadi."}]},"22":{"hr":[{"v":1,"t":"Ako se lopov zateče gdje probija zid, pa mu se zada smrtan udarac, njegovu krv ne treba osvećivati."},{"v":2,"t":"No ako je već izišlo sunce, njegovu krv treba osvetiti. Lopov mora štetu nadoknaditi. Ako nema ništa, njega za njegovu krađu treba prodati."},{"v":3,"t":"Nađe li se ukradeno živinče živo u njegovu vlasništvu - goveče, magare ili koja glava sitne stoke - treba da ga plati dvostruko.”"},{"v":4,"t":"“Tko opustoši njivu ili vinograd pustivši svoju stoku da obrsti tuđe, neka nadoknadi onim što najbolje nađe na svojoj njivi i u svome vinogradu."},{"v":5,"t":"Tko zapali vatru pa ona zahvati drač te izgori žito u snopu, u klasu ili na njivi, onaj tko je vatru zapalio mora štetu nadoknaditi."},{"v":6,"t":"Kad tko položi kod znanca novac ili stvari na čuvanje, pa budu pokradene iz njegove kuće, ako se lopov pronađe, mora dvostruko platiti."},{"v":7,"t":"Ako se lopov ne pronađe, vlasnik kuće neka se primakne k Bogu, da se dokaže kako on nije spustio svoje ruke na dobra svoga bližnjega."},{"v":8,"t":"Za svaki prekršaj pronevjere - radilo se o govečetu, magaretu, sitnoj stoci, odjeći ili bilo kojoj izgubljenoj stvari za koju se ustvrdi: to je ono! - treba spor iznijeti pred Boga. Onaj koga Bog proglasi krivim neka plati dvostruko drugome."},{"v":9,"t":"Kad tko povjeri svome susjedu magare, goveče, glavu sitne stoke ili bilo kakvo živinče, pa ono ugine, osakati se ili ga tko odvede a da ne bude svjedoka,"},{"v":10,"t":"zakletva pred Jahvom neka odluči među obojicom je li čuvar posegao za dobrom svoga bližnjega ili nije. Neka je vlasniku to dovoljno, a čuvar nije dužan da nadoknađuje."},{"v":11,"t":"Nađe li se da je on ukrao, mora štetu nadoknaditi."},{"v":12,"t":"Ako ga zvijer razdere, neka ga donese za dokaz, tako da za razderano ne daje odštete."},{"v":13,"t":"Kad tko posudi živinu na izor od svoga susjeda, pa se ona osakati ili ugine dok joj vlasnik nije bio s njom, neka plati odštetu."},{"v":14,"t":"Je li vlasnik bio s njom, odštete mu ne daje; ali ako je bila unajmljena na izor, neka dođe po svoju nadnicu.”"},{"v":15,"t":"“Ako tko zavede djevojku koja nije zaručena i s njom legne, neka za nju dadne ženidbenu procjenu i uzme je za ženu."},{"v":16,"t":"Ako njezin otac odbije da mu je dadne, zavodnik mora odmjeriti srebra u vrijednosti ženidbene procjene za djevojku."},{"v":17,"t":"Ne dopuštaj da vračarica živi!"},{"v":18,"t":"Tko bi god sa živinom legao, treba ga kazniti smrću."},{"v":19,"t":"Tko bi prinosio žrtve kojemu kumiru - osim Jahvi jedinom - neka bude izručen prokletstvu, potpuno uništen."},{"v":20,"t":"Ne tlači pridošlicu niti mu nanosi nepravde, jer ste i sami bili pridošlice u zemlji egipatskoj."},{"v":21,"t":"Ne cvilite udovice i siročeta!"},{"v":22,"t":"Ako ih ucviliš i oni zavape k meni, sigurno ću njihove vapaje uslišati."},{"v":23,"t":"Moj će se gnjev raspaliti i mačem ću vas pogubiti. Tako će vam žene ostati udovice a djeca siročad."},{"v":24,"t":"Ako uzajmiš novca kome od moga naroda, siromahu koji je kod tebe, ne postupaj prema njemu kao lihvar! Ne nameći mu kamata!"},{"v":25,"t":"Uzmeš li svome susjedu ogrtač u zalog, moraš mu ga vratiti prije zalaza sunca."},{"v":26,"t":"TÓa to mu je jedini pokrivač kojim omata svoje tijelo i u kojem može leći. Ako k meni zavapi, uslišat ću ga jer sam ja milostiv!"},{"v":27,"t":"Ne huli Boga i ne psuj glavara svoga naroda."},{"v":28,"t":"Ne oklijevaj s prinosima od svoga obilja s gumna i od svoga mladog vina! Meni daj prvorođenca od svojih sinova."},{"v":29,"t":"Isto učini sa svojim govedima i sitnom stokom: sedam dana neka ostane sa svojom majkom, a osmoga dana da si ga meni dao!"},{"v":30,"t":"Budite narod meni posvećen! Zato nemojte jesti mesa od životinje koju je rastrgala zvjerad nego je bacite paščadi!”"}]},"23":{"hr":[{"v":1,"t":"“Nemojte davati lažne izjave! Ne pomaži zlikovcu svjedočeći krivo!"},{"v":2,"t":"Ne povodi se za mnoštvom da činiš zlo; niti svjedoči u parnici stajući na stranu većine protiv pravde."},{"v":3,"t":"Ne smiješ biti pristran prema siromahu u njegovoj parnici."},{"v":4,"t":"Kad nabasaš na zalutalo goveče ili magare svoga neprijatelja, moraš mu ga natrag dovesti."},{"v":5,"t":"Ako opaziš magarca onoga koji te mrzi kako je pao pod svojim tovarom, nemoj ga ostaviti: zajedno s njegovim gospodarom moraš mu pomoći da se digne."},{"v":6,"t":"Ne krnji prava svome siromahu u njegovoj parnici."},{"v":7,"t":"Stoj daleko od lažne optužbe; ne ubijaj nedužna i pravedna, jer ja zlikovcu ne praštam."},{"v":8,"t":"Ne primaj mita, jer mito zasljepljuje i one koji najjasnije gledaju i upropašćuje pravo pravednika."},{"v":9,"t":"Ne ugnjetavaj pridošlicu! TÓa znate kako je pridošlici; i sami ste bili pridošlice u zemlji egipatskoj.”"},{"v":10,"t":"“Šest godina zasijavaj svoju zemlju i njezine plodove pobiri,"},{"v":11,"t":"a sedme je godine pusti da počiva neobrađena. Neka se s nje hrani sirotinja tvoga naroda, a što njoj ostane, neka pojede poljska živina. Radi tako i sa svojim vinogradom i svojim maslinikom."},{"v":12,"t":"Šest dana obavljaj svoj posao, ali sedmoga dana od posala odustani, da ti otpočine vo i magarac i da odahne sin tvoje sluškinje i pridošlica."},{"v":13,"t":"Pripazite na sve što sam vam rekao. Ne spominjite imena drugih bogova. Neka se to i ne čuje iz tvojih usta.”"},{"v":14,"t":"“Triput na godinu održavaj u moju čast svetkovinu."},{"v":15,"t":"Slavi Blagdan beskvasnoga kruha. U određeno vrijeme u mjesecu Abibu - jer si u njemu iz Egipta izišao - sedam dana jedi beskvasan kruh, kako sam ti naredio. Neka nitko ne stupa preda me praznih ruku!"},{"v":16,"t":"Onda slavi Blagdan žetve - prvina što ih donose polja koja zasijavaš. Zatim Blagdan berbe na koncu godine, kad s polja pokupiš plodove svoga truda."},{"v":17,"t":"Triput na godinu neka svi tvoji muški stupe pred Gospodara Jahvu."},{"v":18,"t":"Krv žrtve koju u moju čast žrtvuješ nemoj prinositi s ukvasanim kruhom; salo od žrtve prinesene na moju svetkovinu ne ostavljaj za sutradan."},{"v":19,"t":"Donosi u kuću Jahve, svoga Boga, najbolje prvine sa svoje zemlje. Ne kuhaj kozleta u mlijeku njegove majke.”"},{"v":20,"t":"“Šaljem, evo, svog anđela pred tobom da te čuva na putu i dovede te u mjesto koje sam priredio."},{"v":21,"t":"Poštuj ga i slušaj! Ne buni se protiv njega, jer vam neće opraštati prekršaje: tÓa moje je ime u njemu."},{"v":22,"t":"Ako mu se budeš vjerno pokoravao i budeš vršio sve što sam naredio, ja ću biti neprijatelj tvojim neprijateljima i protivnik tvojim protivnicima."},{"v":23,"t":"Anđeo će moj ići pred tobom i dovesti te do Amorejaca, Hetita, Perižana, Kanaanaca, Hivijaca i Jebusejaca da ih uništim."},{"v":24,"t":"Nemoj se klanjati njihovim kumirima niti im iskazuj štovanje; ne postupaj kako oni rade nego njihove kumire poruši i stupove im porazbijaj."},{"v":25,"t":"Iskazujte štovanje Jahvi, Bogu svome, pa ću blagoslivati tvoj kruh i tvoju vodu i uklanjati od tebe bolest."},{"v":26,"t":"U tvojoj zemlji neće biti pometkinje; ja ću učiniti punim broj tvojih dana."},{"v":27,"t":"Pred tobom ću odaslati stravu svoju; u metež ću baciti sav svijet među koji dospiješ i učinit ću da svi tvoji neprijatelji bježe pred tobom."},{"v":28,"t":"Stršljene ću pred tobom odašiljati da ispred tebe tjeraju u bijeg Hivijce, Kanaance i Hetite."},{"v":29,"t":"Neću ih otjerati ispred tebe u jednoj godini, da zemlja ne opusti i divlje se životinje ne razmnože na tvoju štetu."},{"v":30,"t":"Tjerat ću ih ispred tebe malo-pomalo dok ti potomstvo ne odraste, tako da zemlju zaposjedneš."},{"v":31,"t":"Postavit ću ti granicu: od Crvenoga do Filistejskoga mora, od pustinje pa do Rijeke. Predat ću, naime, stanovništvo zemlje u tvoje šake, a ti ga ispred sebe tjeraj."},{"v":32,"t":"Ne pravi savez ni s njima ni s njihovim kumirima."},{"v":33,"t":"Neka ne ostanu u tvojoj zemlji da te ne navode na grijeh protiv mene. Ako bi štovao njihove kumire, to bi ti bila stupica.”"}]},"24":{"hr":[{"v":1,"t":"Potom reče Mojsiju: “Uzađi k Jahvi - ti, Aron, Nadab i Abihu i sedamdeset izraelskih starješina. Poklonite se izdaljega!"},{"v":2,"t":"Neka se sam Mojsije primakne k Jahvi! Oni neka se ne primiču, a puk neka se s njim ne penje.”"},{"v":3,"t":"Dođe Mojsije i kaza narodu sve riječi Jahvine i sve odredbe. A sav puk odgovori u jedan glas: “Sve riječi što ih Jahve reče, vršit ćemo.”"},{"v":4,"t":"Tada Mojsije popiše sve riječi Jahvine. A ujutro podrani te podigne žrtvenik na podnožju brda i dvanaest stupova za dvanaest plemena Izraelovih."},{"v":5,"t":"Zatim naloži mladim Izraelcima da prinesu žrtve paljenice i da žrtvuju Jahvi junce kao žrtve pričesnice."},{"v":6,"t":"Mojsije uhvati krv; polovinu krvi ulije u posude, a polovinu izlije po žrtveniku."},{"v":7,"t":"Prihvati zatim Knjigu Saveza pa je narodu glasno pročita, a narod uzvrati: “Sve što je Jahve rekao, izvršit ćemo i poslušat ćemo.”"},{"v":8,"t":"Mojsije potom uzme krvi te poškropi narod govoreći: “Ovo je krv Saveza koji je Jahve s vama uspostavio na temelju svih ovih riječi.”"},{"v":9,"t":"Onda se uspne Mojsije s Aronom, Nadabom i Abihuom i sa sedamdeset starješina Izraelovih."},{"v":10,"t":"Oni vidješe Boga Izraelova: podnožje njegovim nogama kao da je bilo od dragoga kamena safira, sjajem nalik na samo nebo."},{"v":11,"t":"Ni ruke svoje nije pružio na izabranike Izraelaca: slobodno su Boga motrili i jeli i pili."},{"v":12,"t":"Onda Jahve reče Mojsiju: “Popni se k meni na brdo i pričekaj ondje. Dat ću ti kamene ploče sa zakonom i zapovijedima koje sam za njihovu pouku napisao.”"},{"v":13,"t":"Ustane Mojsije i njegov pomoćnik Jošua te se Mojsije popne na brdo Božje."},{"v":14,"t":"A starješinama reče: “Čekajte nas ovdje dok se ne vratimo. Eto je s vama Aron i Hur. Tko imadne kakvu razmiricu, neka se obrati na njih.”"},{"v":15,"t":"Zatim Mojsije uzađe na brdo, a onda oblak prekri brdo."},{"v":16,"t":"Slava se Jahvina nastani na Sinajskom brdu i oblak ga obavijaše šest dana. Sedmoga dana zovne Jahve Mojsija isred oblaka."},{"v":17,"t":"Slava Jahvina na vrhuncu brda bijaše očima Izraelaca kao vatra koja sažiže. Mojsije zađe u oblak i uspne se na brdo."},{"v":18,"t":"Četrdeset dana i četrdeset noći boravio je Mojsije na brdu."}]},"25":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Reci Izraelcima da me darivaju, a vi primajte darove u moju čast od svakoga koji daje od srca."},{"v":3,"t":"A primajte ove darove: zlato, srebro i tuč;"},{"v":4,"t":"ljubičasto, crveno i tamnocrveno predivo i prepredeni lan;"},{"v":5,"t":"učinjene ovnujske kože, pa fine kože; bagremovo drvo;"},{"v":6,"t":"ulje za svjetlo; mirodije za ulje pomazanja i miomirisno kađenje;"},{"v":7,"t":"oniks i drugo drago kamenje koje će se umetnuti u oplećak i naprsnik."},{"v":8,"t":"Neka mi sagrade Svetište da mogu boraviti među njima."},{"v":9,"t":"Pri gradnji Prebivališta i svega u njemu postupi točno prema uzorku koji ti pokažem.”"},{"v":10,"t":"“Od bagremova drva neka naprave Kovčeg: dva i po lakta dug, lakat i po širok i lakat i po visok."},{"v":11,"t":"Okuj ga čistim zlatom, okuj ga izvana i iznutra; a oko njega stavi naokolo završni pojas od zlata."},{"v":12,"t":"Salij za nj četiri zlatna koluta; prikuj ih za četiri njegove noge; dva koluta s jedne strane, a dva s druge."},{"v":13,"t":"Od bagremova drva napravi i motke te ih u zlato okuj."},{"v":14,"t":"Onda provuci motke kroz kolutove sa strana Kovčega da se na njima Kovčeg nosi."},{"v":15,"t":"Neka motke ostanu u kolutima Kovčega; neka se iz njih ne izvlače."},{"v":16,"t":"Svjedočanstvo koje ću ti predati - u Kovčeg položi.”"},{"v":17,"t":"“Pomirilište napravi također od čistoga zlata. Neka bude dugo dva i pol lakta, a široko lakat i pol."},{"v":18,"t":"Skuj i dva kerubina od zlata za oba kraja Pomirilišta."},{"v":19,"t":"Napravi jednoga kerubina za jedan kraj, a drugoga kerubina za drugi kraj. Pričvrsti ih na oba kraja Pomirilišta da s njim sačinjavaju jedan komad."},{"v":20,"t":"Kerubini neka dignu svoja krila uvis tako da svojim krilima zaklanjaju Pomirilište. Neka budu licem okrenuti jedan prema drugome, ali tako da lica kerubina gledaju u Pomirilište."},{"v":21,"t":"Stavi na Kovčeg Pomirilište, a u Kovčeg položi ploče Svjedočanstva što ću ti ih dati."},{"v":22,"t":"Tu ću se ja s tobom sastajati i ozgo ću ti, iznad Pomirilišta - između ona dva kerubina što su na Kovčegu ploča Svjedočanstva - saopćavati sve zapovijedi namijenjene Izraelcima.”"},{"v":23,"t":"“Napravi od bagremova drva stol dva lakta dug, lakat širok, a lakat i pol visok."},{"v":24,"t":"U čisto ga zlato obloži i načini mu naokolo završni pojas od zlata."},{"v":25,"t":"Naokolo mu načini obrub, podlanicu širok, a onda po obrubu stavi završni pojas od zlata."},{"v":26,"t":"Nadalje, uspravi mu četiri koluta od zlata pa mu ih pričvrsti na njegova četiri nožna ugla."},{"v":27,"t":"Neka su kolutovi tik pod obrubom da služe kao kvake motkama za nošenje stola."},{"v":28,"t":"Motke napravi od bagremova drva i u zlato ih okuj. O njima će se stol nositi."},{"v":29,"t":"Za nj onda napravi: zdjele, varjače, vrčeve i pehare za izlijevanje prinosa. Načini ih od čistoga zlata."},{"v":30,"t":"Na stol svagda stavljaj pred moje lice prineseni kruh.”"},{"v":31,"t":"“Načini svijećnjak od čistoga zlata. Svijećnjak neka bude skovan. Njegovo podnožje, njegov stalak, njegove čaše, čaške i latice - sve neka bude od jednoga komada."},{"v":32,"t":"Šest krakova neka mu izbija sa strana: tri kraka s jedne strane stalka, a tri kraka s druge strane stalka."},{"v":33,"t":"Na jednome kraku neka budu tri čaše u obliku bademova cvijeta, svaka s čaškom i laticama. Tako za svih šest krakova što budu izbijali iz stalka svijećnjaka."},{"v":34,"t":"Na samome svijećnjaku neka budu četiri čaše u obliku bademova cvijeta, svaka s čaškom i laticama."},{"v":35,"t":"Čaška ispod dva kraka, sačinjavajući jedan komad s njime; onda čaška ispod druga dva kraka, od jednoga komada s njime, pa čaška ispod dva posljednja kraka, od jednoga komada s njime. Tako za svih šest krakova što iz stalka budu izbijali."},{"v":36,"t":"Njihove čaške i njihovi krakovi sačinjavat će jedan komad s njim - sve skovano u jednome komadu od čistoga zlata."},{"v":37,"t":"Napravi i sedam svjetiljaka za njih. Svjetiljke neka tako budu postavljene da osvjetljuju prostor sprijeda."},{"v":38,"t":"Usekači i pepeljare za njih neka su od čistoga zlata."},{"v":39,"t":"Upotrijebi talenat čistoga zlata za svijećnjak i sav njegov pribor."},{"v":40,"t":"Pazi! Načini ih prema uzorku koji ti je na brdu pokazan.”"}]},"26":{"hr":[{"v":1,"t":"“Prebivalište načini od deset zavjesa: od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana. Na njima neka budu vezeni likovi kerubina - djelo umjetnika."},{"v":2,"t":"Dužina svake zavjese neka je dvadeset i osam lakata, neka joj je širina četiri lakta. Sve zavjese neka su iste mjere."},{"v":3,"t":"Pet zavjesa neka su sastavljene jedna s drugom, a drugih pet zavjesa opet jedna s drugom."},{"v":4,"t":"Napravi petlje od ljubičaste vune pri rubu krajnje zavjese u sastavljenom komadu."},{"v":5,"t":"Napravi pedeset petlji na rubu jednoga sastavljenog komada od zavjesa, a pedeset pri rubu drugoga. Neka su petlje načinjene jedna spram druge."},{"v":6,"t":"Onda napravi pedeset kopča od zlata. Zavjese zatim kopčama sastavi jednu s drugom. Tako će Prebivalište biti jedna cjelina."},{"v":7,"t":"Načini zatim zavjese od kostrijeti za Šator povrh Prebivališta. Načini ih jedanaest."},{"v":8,"t":"Neka duljina svake zavjese bude trideset lakata, a širina svake zavjese četiri lakta. Tih jedanaest zavjesa neka bude iste mjere."},{"v":9,"t":"Sastavi pet zavjesa napose, a onda opet drugih šest zavjesa napose. Šestu zavjesu podvostruči na pročelju Šatora."},{"v":10,"t":"Ušij pedeset petlji na rubu jednoga sastavljenog komada od zavjesa, a pedeset na rubu drugoga."},{"v":11,"t":"Izradi pedeset kopča od tuča, zapni kopče za petlje da sastaviš Šator u cjelinu."},{"v":12,"t":"A kako će zavjese od Šatora pretjecati, neka se polovina zavjesa što preostane spušta na zadnjem dijelu Prebivališta."},{"v":13,"t":"Od onoga što preteče na dužini šatorskih zavjesa neka po jedan lakat visi na obje strane svetoga Šatora da ga zaklanja."},{"v":14,"t":"Napokon napravi Šatoru pokrov od učinjenih i u crveno obojenih ovnujskih koža, a povrh njega pokrov od finih koža."},{"v":15,"t":"Trenice što će nauzgor stajati za Prebivalište napravi od bagremova drva."},{"v":16,"t":"Svaka trenica neka bude deset lakata duga, a lakat i pol široka."},{"v":17,"t":"Svaka trenica neka ima dva klina da je uspravno drže. Tako napravi na svakoj trenici za Prebivalište."},{"v":18,"t":"Trenice za Prebivalište postavi: dvadeset trenica s juga, prema podnevu;"},{"v":19,"t":"onda pod dvadeset trenica napravi četrdeset podnožja od srebra, dva podnožja pod prvu trenicu za njezina dva klina, i tako redom, dva podnožja za dva klina svake slijedeće trenice."},{"v":20,"t":"Za drugu stranu Prebivališta, sa sjevera: dvadeset trenica"},{"v":21,"t":"i četrdeset srebrnih podnožja, dva podnožja za dva klina prve trenice, i tako redom, dva podnožja za svaku trenicu."},{"v":22,"t":"Na stražnjoj strani Prebivališta, sa zapada, postavi šest trenica."},{"v":23,"t":"Napravi i dvije trenice za stražnje uglove Prebivališta."},{"v":24,"t":"Neka budu rastavljene pri dnu, ali na vrhu kod prvoga koluta neka budu sastavljene. Neka tako obadvije prave dva ugla."},{"v":25,"t":"Neka dakle bude osam trenica s njihovim srebrnim podnožjima: šesnaest podnožja, dva podnožja pod prvom trenicom, a dva opet podnožja pod svakom slijedećom trenicom."},{"v":26,"t":"Nadalje napravi priječnice od bagremova drva: pet njih za trenice s jedne strane Prebivališta,"},{"v":27,"t":"a pet priječnica s druge strane Prebivališta; onda pet priječnica za trenice Prebivališta straga prema zapadu."},{"v":28,"t":"Srednja priječnica neka ide sredinom trenica s jednoga kraja na drugi."},{"v":29,"t":"Trenice obloži zlatom, a i kolutove za njih, kroz koje će se priječnice provlačiti, načini od zlata. Priječnice onda obloži zlatom."},{"v":30,"t":"Tako, dakle, podigni Prebivalište prema nacrtu koji ti je pokazan na brdu.”"},{"v":31,"t":"“Napravi zavjesu od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana. Neka su na njoj izvezeni kerubini."},{"v":32,"t":"Objesi je na četiri stupa od bagremova drva, zlatom obložena, s kopčama od zlata, a na četiri podnožja od srebra."},{"v":33,"t":"Objesi zavjesu za kvake. Onda unesi Kovčeg svjedočanstva tu za zavjesu. Neka ti tako zavjesa odjeljuje Svetište od Svetišta nad svetištima."},{"v":34,"t":"Stavi Pomirilište na Kovčeg svjedočanstva u Svetinji nad svetinjama."},{"v":35,"t":"Postavi zatim stol van pred zavjesu, a svijećnjak na južnu stranu Prebivališta, prema stolu. Stol stavi na sjevernu stranu."},{"v":36,"t":"A na ulazu u Šator napravi zastorak od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana - vezom izvezen."},{"v":37,"t":"Za zastorak isteši pet stupčića od bagrenova drva pa ih obloži zlatom. Kopče za njih neka budu od zlata. Salij za njih pet podnožja od tuča.”"}]},"27":{"hr":[{"v":1,"t":"“Načini žrtvenik od bagremova drva, pet lakata dug, pet lakata širok - prava četvorina - i tri lakta visok."},{"v":2,"t":"Na njegova četiri ugla načini rogove. Neka mu rogovi budu u jednome komadu s njim. I tučem ga okuj."},{"v":3,"t":"Dalje, načini za žrtvenik posude za zgrtanje otpadaka: strugače, kotliće, viljuške i kadionike. Sve potrepštine za žrtvenik načini od tuča."},{"v":4,"t":"Onda načini za nj rešetku od tuča, u obliku mrežice,"},{"v":5,"t":"a na četiri ugla mrežicu ispod izbočine žrtvenika, tako da zahvati do sredine žrtvenika."},{"v":6,"t":"Napravi zatim motke za žrtvenik, motke od bagremova drva, pa ih tučem okuj."},{"v":7,"t":"Neka se motke provuku kroz kolutove, tako da dođu na obje strane žrtvenika kad se nosi."},{"v":8,"t":"Načini ga šuplja, od dasaka: kako ti je pokazano na brdu, onako neka je i napravljen.”"},{"v":9,"t":"“Napravi i dvorište Prebivališta. Na južnoj strani napravi zavjese od prepredenog lana, sto lakata u dužinu s te strane."},{"v":10,"t":"Njihovih dvadeset stupova neka stoji na dvadeset podnožja od tuča i neka imaju kopče i šipke od srebra."},{"v":11,"t":"Isto tako za sjevernu stranu načini plahte sto lakata duge. Njihovih dvadeset stupova i dvadeset podnožja od tuča, ali kopče i šipke neka su od srebra."},{"v":12,"t":"Širini dvorišta sa zapadne strane trebat će zavjese pedeset lakata duge, sa deset stupova i deset podnožja."},{"v":13,"t":"Širina dvorišta prema istočnoj strani neka bude pedeset lakata."},{"v":14,"t":"Nadalje, zavjese s jedne strane vrata neka su petnaest lakata duge, sa svoja tri stupa i njihova tri podnožja."},{"v":15,"t":"A s druge strane neka su zavjese opet petnaest lakata, sa svoja tri stupa i njihova tri podnožja."},{"v":16,"t":"Za dvorišni ulaz: vezen zastor od dvadeset lakata, od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana; i sa svoja četiri stupa i njihova četiri podnožja."},{"v":17,"t":"Svi stupovi naokolo dvorišta neka su povezani srebrnim šipkama. Neka su im kopče od srebra, a podnožja od tuča."},{"v":18,"t":"Neka je dvorište u duljinu sto lakata, u širinu pedeset, a u visinu pet lakata. Neka su mu plahte od prepredenog lana, podnožja od tuča."},{"v":19,"t":"Sve potrepštine u Prebivalištu za opću upotrebu i svi njegovi kočići, a tako i kočići u dvorištu, neka su od tuča.”"},{"v":20,"t":"“Nadalje, naredi Izraelcima da ti za svjetlo donose čistoga ulja od istupanih maslina, tako da svjetlo neprestano gori."},{"v":21,"t":"Aron i njegovi sinovi neka ga postavljaju u Šator sastanka izvan zavjese što zaklanja Svjedočanstvo da gori pred Jahvom od večeri do jutra. Neka je to neopoziva naredba za izraelske naraštaje.”"}]},"28":{"hr":[{"v":1,"t":"“A onda dovedi k sebi između Izraelaca svoga brata Arona zajedno s njegovim sinovima: Nadabom, Abihuom, Eleazarom i Itamarom da mi služe kao svećenici."},{"v":2,"t":"Napravi svome bratu Aronu sveto ruho na čast i ukras."},{"v":3,"t":"Obrati se svim vještacima koje sam obdario mudrošću neka naprave haljine Aronu da bi se posvetio i vršio svećeničku službu u moju čast."},{"v":4,"t":"Neka ovu odjeću naprave: naprsnik, oplećak, ogrtač, košulju resama obrubljenu, mitru i pas; neka naprave svetu odjeću za tvoga brata Arona i njegove sinove da mi služe kao svećenici."},{"v":5,"t":"Stoga neka oni primaju zlato, ljubičasto, crveno i tamnocrveno predivo i prepredeni lan.”"},{"v":6,"t":"“Oplećak neka naprave od zlata, od ljubičastog, crvenog i tamnocrvenog prediva i od prepredenog lana - vješto izrađen."},{"v":7,"t":"Neka na njemu budu dvije poramenice, pričvršćene za njegove krajeve."},{"v":8,"t":"Tkanica što bude na njemu neka je napravljena kao i on: od zlata, od ljubičastog, crvenog i tamnocrvenog prediva i od prepredenog lana, a neka s njim sačinjava jedan komad."},{"v":9,"t":"Zatim uzmi dva draga kamena oniksa i u njih ureži imena Izraelovih sinova:"},{"v":10,"t":"šest njihovih imena na jednome dragom kamenu, a preostalih šest imena na drugome dragom kamenu, prema njihovu rođenju."},{"v":11,"t":"Kao što rezbar dragulja urezuje pečate na prstene, tako ti ureži imena Izraelovih sinova. Oko njih navezi zlatan obrub,"},{"v":12,"t":"pa pričvrsti oba draga kamena za poramenice oplećka da budu spomen-dragulji na Izraelove sinove. Tako neka Aron nosi njihova imena o svoja dva ramena pred Jahvom da ih se sjeća."},{"v":13,"t":"Načini zlatne okvire"},{"v":14,"t":"i dva lančića od čistoga zlata. Načini ih kao zasukane uzice i onda zasukane lančiće pričvrsti za okvire.”"},{"v":15,"t":"“Naprsnik za presuđivanje izradi umjetnički; izvedi to kao i posao na oplećku: od zlata, od ljubičastog, crvenog i tamnocrvenog prediva i od prepredenog lana."},{"v":16,"t":"Neka bude četvorinast i dvostruk; jedan pedalj neka mu je duljina, a pedalj širina."},{"v":17,"t":"Na njemu poredaj četiri reda dragulja. U prvome redu neka bude: rubin, topaz i alem;"},{"v":18,"t":"u drugome redu: smaragd, safir i ametist;"},{"v":19,"t":"u trećem redu: hijacint, ahat i ledac;"},{"v":20,"t":"a u četvrtom redu: krizolit, oniks i jaspis. Neka budu ukovani u zlatne okvire."},{"v":21,"t":"Tih dragulja neka bude dvanaest, koliko i imena Izraelovih sinova. Neka budu urezani kao i pečati na prstenju, svaki s imenom jednoga od dvanaest plemena."},{"v":22,"t":"Napravi za naprsnik lančiće od čistoga zlata, zasukane kao uzice."},{"v":23,"t":"Zatim napravi za naprsnik dva kolutića od zlata i pričvrsti ih na dva gornja ugla naprsnika."},{"v":24,"t":"Onda priveži dvije zlatne uzice za ta dva kolutića koja budu pričvršćena za uglove naprsnika."},{"v":25,"t":"Druga dva kraja uzica priveži za dva okvira. Sad ih tako pričvrsti za poramenice oplećka sprijeda."},{"v":26,"t":"Napravi dva kolutića od zlata pa ih pričvrsti za dva donja ugla naprsnika, uz rub iznutra koji je okrenut prema oplećku."},{"v":27,"t":"Napravi još dva kolutića od zlata i pričvrsti ih za donji, prednji kraj poramenice oplećka, uz njegov šav povrh tkanice oplećka."},{"v":28,"t":"Neka se naprsnik sveže za svoje kolutiće s kolutićima oplećka vrpcom od modroga grimiza, tako da naprsnik stoji iznad tkanice i da se ne može odvajati od oplećka."},{"v":29,"t":"Neka tako Aron, kada god ulazi u Svetište, na svome srcu nosi imena sinova Izraelovih na naprsniku za presuđivanje da ih uvijek doziva u sjećanje pred Jahvom."},{"v":30,"t":"U naprsnik za presuđivanje neka se stave i 'Urim' i 'Tumim' da i oni budu na Aronovu srcu kad bude dolazio pred Jahvu. Tako neka Aron uvijek na svom srcu pred Jahvom nosi presudu sinova Izraelovih.”"},{"v":31,"t":"“Ogrtač za oplećak sav napravi od ljubičastog prediva."},{"v":32,"t":"Prorez za glavu na njemu neka bude na sredini. Rub naokolo proreza neka bude opšiven kao ovratnik na oklopu, tako da se ogrtač ne podere."},{"v":33,"t":"Na njegovu rubu sve naokolo načini šipke od ljubičastog, crvenog i tamnocrvenog prediva, a između njih zvonca od zlata naokolo;"},{"v":34,"t":"zlatno zvonce pa šipak, zlatno zvonce pa šipak naokolo ogrtača uz rub."},{"v":35,"t":"Neka budu na Aronu dok vrši službu, da se čuje kad ulazi u Svetište pred Jahvu i kad izlazi; tako neće umrijeti.”"},{"v":36,"t":"“Napravi potom jednu ploču od čistoga zlata i na njoj ureži, kao što se urezuje na pečatnom prstenu: 'Jahvi posvećen'."},{"v":37,"t":"Za mitru je priveži modrom vrpcom da stoji s pročelja mitre."},{"v":38,"t":"Neka stoji na Aronovu čelu. Tako neka Aron na se preuzme nedostatke koji bi mogli okaljati sve svete prinose što ih Izraelci posvećuju. Neka uvijek stoji na njegovu čelu da za njih stječe blagonaklonost Jahvinu."},{"v":39,"t":"Košulju s resama napravi od lana, od lana napravi i mitru, a pas vezom izvezi."},{"v":40,"t":"I za Aronove sinove napravi haljine, pasove i turbane, njima na čast i ukras."},{"v":41,"t":"U njih odjeni svoga brata Arona i njegove sinove; onda ih pomaži, ispuni im ruke vlašću i posveti ih da mi služe kao svećenici."},{"v":42,"t":"Napravi za njih gaćice od lana da im pokriju golo tijelo. Neka sežu od bedara do stegna."},{"v":43,"t":"Neka ih nosi Aron i njegovi sinovi kad ulaze u Šator sastanka ili kad se primiču žrtveniku za službu u Svetištu da ne navuku na se krivnju i umru. To neka bude vječna naredba za nj i za njegovo potomstvo poslije njega.”"}]},"29":{"hr":[{"v":1,"t":"“Ovo je obred koji ćeš obaviti na njima da ih posvetiš za moje svećenike: Uzmi jednog junca i dva ovna bez mane;"},{"v":2,"t":"onda beskvasnoga kruha, beskvasnih kolača zamiješenih u ulju i beskvasnih prevrta uljem namazanih. Napravi ih od bijeloga pšeničnog brašna."},{"v":3,"t":"Naslaži ih u košaricu i u košarici prinesi ih s juncem i oba ovna.”"},{"v":4,"t":"“Dovedi Arona i njegove sinove k ulazu u Šator sastanka i operi ih u vodi."},{"v":5,"t":"Zatim uzmi odijelo i obuci Arona u košulju; stavi na nj ogrtač oplećka, oplećak i naprsnik i opaši ga tkanicom oplećka."},{"v":6,"t":"Ustakni mu mitru na glavu; na mitru stavi sveti vijenac."},{"v":7,"t":"Uzmi zatim ulja za pomazanje; izlij na njegovu glavu i pomaži ga."},{"v":8,"t":"Onda dovedi njegove sinove; obuci ih u košulje;"},{"v":9,"t":"opaši ih u pasove i obvij im turbane. Svećeništvo neka im pripada vječnom uredbom. Tako posveti Arona i njegove sinove!”"},{"v":10,"t":"“Dovedi zatim junca pred Šator sastanka, pa neka Aron i njegovi sinovi stave ruke juncu na glavu."},{"v":11,"t":"Onda pred Jahvom, na ulazu u Šator sastanka, junca zakolji."},{"v":12,"t":"Uzmi junčeve krvi i svojim je prstom stavi na rogove žrtvenika. Ostatak krvi izlij podno žrtvenika."},{"v":13,"t":"Uzmi sav loj oko droba, privjesak na jetri i oba bubrega s lojem oko njih, pa spali na žrtveniku."},{"v":14,"t":"Meso od junca, njegovu kožu i njegovu nečist spali na vatri izvan taborišta. To je žrtva okajnica."},{"v":15,"t":"Poslije toga uzmi jednoga ovna, pa neka Aron i njegovi sinovi stave na njegovu glavu svoje ruke."},{"v":16,"t":"Onda ovna zakolji, uhvati mu krvi i zapljusni njome žrtvenik sa svih strana."},{"v":17,"t":"Isijeci zatim ovna u komade, operi mu drobinu i noge i položi ih na njegove ostale dijelove i glavu."},{"v":18,"t":"I onda cijeloga ovna spali na žrtveniku. Žrtva je to paljenica u čast Jahvi, miris ugodan, žrtva ognjena."},{"v":19,"t":"Uzmi onda drugoga ovna, pa neka Aron i njegovi sinovi stave svoje ruke ovnu na glavu."},{"v":20,"t":"Sad ovna zakolji; uzmi mu krvi i njome namaži resicu desnoga Aronova uha, resicu desnog uha njegovim sinovima, palac na njihovoj desnoj ruci pa palac na njihovoj desnoj nozi. Ostatkom krvi zapljusni žrtvenik naokolo."},{"v":21,"t":"Uzmi onda krvi što je ostala na žrtveniku i ulja za pomazanje i poškropi Arona i njegovo odijelo, njegove sinove i njihova odijela. Tako će biti posvećen on i njegovo odijelo, njegovi sinovi i odijela njegovih sinova.”"},{"v":22,"t":"“Poslije toga uzmi s ovna loj, pretili rep, loj oko droba, privjesak s jetre, oba bubrega i loj oko njih; desno pleće - jer je to ovan prinesen za svećeničko posvećenje -"},{"v":23,"t":"zatim jedan okrugli kruh, jedan kolač na ulju i jednu prevrtu iz košarice beskvasnoga kruha što je pred Jahvom."},{"v":24,"t":"Sve to stavi na ruke Arona i njegovih sinova i prinesi žrtvu prikaznicu pred Jahvom."},{"v":25,"t":"Uzmi ih onda s njihovih ruku i spali na žrtveniku, povrh žrtve paljenice, da bude Jahvi na ugodan miris. To je paljena žrtva u čast Jahvi."},{"v":26,"t":"Zatim uzmi grudi ovna prinesena za Aronovo posvećenje i prinesi ih kao žrtvu prikaznicu pred Jahvom. Neka to bude tvoj dio."},{"v":27,"t":"Posveti grudi što su bile prinesene kao žrtva prikaznica i pleće što je bilo prineseno kao žrtva podizanica od ovna prinesena za posvećenje Arona i njegovih sinova."},{"v":28,"t":"Neka to bude pristojba Aronu i njegovim potomcima od Izraelaca za sva vremena. TÓa to je ujam koji će Izraelci davati od svojih pričesnica - ujam koji Jahvi pripada."},{"v":29,"t":"Aronova posvećena odijela neka pripadnu njegovim sinovima poslije njega da u njima budu pomazani i posvećeni."},{"v":30,"t":"Sin koji postane svećenikom mjesto njega, kad uđe u Šator sastanka da vrši službu u Svetištu, neka ih nosi sedam dana.”"},{"v":31,"t":"“Uzmi onda ovna za posvećenje i skuhaj njegovo meso na posvećenome mjestu."},{"v":32,"t":"Aron i njegovi sinovi neka blaguju meso od toga ovna i kruh iz košarice na ulazu u Šator sastanka."},{"v":33,"t":"Neka jedu od onoga što je poslužilo za njihovo očišćenje, da im se ruke ispune vlašću i da budu posvećeni. Nijedan svjetovnjak neka ne jede od toga jer je posvećeno."},{"v":34,"t":"Ako bi ostalo što mesa od svećeničkog posvećenja ili što od onoga kruha do ujutro, spali na vatri. Ne smije se pojesti jer je posvećeno.”"},{"v":35,"t":"“Točno tako učini Aronu i njegovim sinovima kako sam ti naredio. Posvećuj ih sedam dana."},{"v":36,"t":"Svakoga dana prinesi jednoga junca kao žrtvu okajnicu - za pomirenje. I prinesi žrtvu okajnicu za pomirenje oltara, zatim ga pomaži da bude posvećen."},{"v":37,"t":"Sedam dana prinosi žrtvu pomirnicu za žrtvenik i posvećuj ga. Tako će žrtvenik postati presvet, i sve što se žrtvenika dotakne bit će posvećeno.”"},{"v":38,"t":"“A ovo treba da prinosiš na žrtveniku: dva janjca godinu dana stara, svaki dan bez prijekida."},{"v":39,"t":"Jedno janje žrtvuj ujutro, a drugo uvečer."},{"v":40,"t":"Prinesi s prvim janjetom jednu desetinu efe bijeloga brašna zamiješena u četvrtini hina istupanog ulja i žrtvu ljevanicu od četvrtine hina vina."},{"v":41,"t":"Drugo janje prinesi u suton. S njim prinesi žrtvu prinosnicu s njezinom žrtvom ljevanicom kao i izjutra - na ugodan miris, žrtvu u čast Jahvi paljenu."},{"v":42,"t":"Neka to bude trajna žrtva paljenica od koljena do koljena - na ulazu u Šator sastanka, pred Jahvom. Tu ću se ja s tobom sastajati da ti govorim."},{"v":43,"t":"I s Izraelcima ću se tu sastajati, i moja će ih slava posvećivati."},{"v":44,"t":"Ja ću posvetiti Šator sastanka i žrtvenik; posvetit ću Arona i njegove sinove da mi služe kao svećenici."},{"v":45,"t":"Ja ću prebivati među Izraelcima i biti njihov Bog."},{"v":46,"t":"Upoznat će oni tada da sam to ja, Jahve, Bog njihov koji ih je izbavio iz zemlje egipatske da prebivam među njima - ja, Jahve, Bog njihov.”"}]},"30":{"hr":[{"v":1,"t":"“Napravi i žrtvenik za paljenje tamjana; napravi ga od bagremova drva."},{"v":2,"t":"Neka bude lakat dug, lakat širok, u pravokut, i dva lakta visok. Neka mu roščići budu od jednoga komada s njim."},{"v":3,"t":"Obloži mu u čisto zlato: njegovu gornju plohu, njegove strane naokolo i njegove roščiće. Načini mu zlatan završni pojas naokolo."},{"v":4,"t":"Načini mu dva zlatna koluta. Pričvrsti mu ih s dviju suprotnih strana ispod završnog pojasa. Kroz njih će se provlačiti motke za nošenje."},{"v":5,"t":"Motke načini od bagremova drva i zlatom ih obloži."},{"v":6,"t":"Postavi žrtvenik pred zavjesu što zastire Kovčeg Svjedočanstva - nasuprot Pomirilištu nad Svjedočanstvom - gdje ću se ja s tobom sastajati."},{"v":7,"t":"Neka na njemu Aron pali miomirisni tamjan svako jutro kad priprema svjetla;"},{"v":8,"t":"neka ga Aron opet pali u suton kad svjetla zapaljuje, da to bude svagdašnje kadiono prinošenje pred Jahvom u sve vaše naraštaje."},{"v":9,"t":"Ne prinosi na njemu ni neposvećenoga tamjana, ni paljenice, ni prinosnice, ni ljevanice!"},{"v":10,"t":"Jednom u godini neka Aron obavi obred pomirenja na njegovim roščićima. Krvlju žrtve koja se prinosi za grijeh, jednom na godinu, neka obavi obred pomirenja za žrtvenik. Tako činite u sve naraštaje. Jer oltar je presveta svetinja Jahvina.”"},{"v":11,"t":"Nadalje Jahve reče Mojsiju:"},{"v":12,"t":"“Kad budeš pravio popis Izraelaca prilikom novačenja, neka svatko da Jahvi otkupninu za se kad se upiše, da ih kakvo zlo ne snađe zbog novačenja."},{"v":13,"t":"Tko god potpada pod novačenje, ovoliko neka dadne: pola šekela - prema hramskom šekelu, gdje je dvadeset gera u šekelu. To pola šekela neka bude kao prinos Jahvi."},{"v":14,"t":"Tko god potpada pod novačenje, od dvadeset godina starosti pa naviše, neka dadne prinos Jahvi."},{"v":15,"t":"Bogataš neka ne plaća više niti siromah manje od pola šekela kad daju prinos Jahvi kao otkup za se."},{"v":16,"t":"Uzimaj otkupni novac od Izraelaca i određuj ga za potrebe Šatora sastanka. Neka to bude Jahvi na spomen da se sjeća Izraelaca i da im bude milostiv.”"},{"v":17,"t":"Reče Jahve Mojsiju:"},{"v":18,"t":"“Napravi umivaonik od tuča i podnožje od tuča za umivanje. Postavi ga između Šatora sastanka i žrtvenika. Nalij u nj vode"},{"v":19,"t":"pa neka Aron i njegovi sinovi peru svoje ruke i noge vodom iz njega."},{"v":20,"t":"Kad moradnu ulaziti u Šator sastanka, ili kad se moradnu primicati žrtveniku za službu da spaljuju žrtve u čast Jahvi paljene, neka se vodom operu da ne poginu."},{"v":21,"t":"Neka operu ruke svoje i noge svoje da izbjegnu smrti: to je trajna naredba Aronu i njegovim potomcima u sve naraštaje.”"},{"v":22,"t":"Još reče Jahve Mojsiju:"},{"v":23,"t":"“Nabavi najboljih mirodija: pet stotina šekela smirne samotoka, pola te težine - dvjesta pedeset - mirisavog cimeta, dvjesta pedeset mirisave trstike,"},{"v":24,"t":"pet stotina - prema hramskom šekelu - lovorike i jedan hin maslinova ulja."},{"v":25,"t":"Od toga napravi posvećeno ulje za pomazanje; da bude smjesa kao da ju je pravio pomastar. Neka to bude posvećeno ulje za pomazanje."},{"v":26,"t":"Time onda pomaži: Šator sastanka i Kovčeg Svjedočanstva;"},{"v":27,"t":"stol i sav njegov pribor; svijećnjak i sav njegov pribor; žrtvenik kadioni;"},{"v":28,"t":"žrtvenik za žrtve paljenice i sav njegov pribor; umivaonik i njegov stalak:"},{"v":29,"t":"posveti ih, i oni će tako postati posvećeni; i što god ih se dotakne, posvećeno će postati."},{"v":30,"t":"Pomaži Arona i njegove sinove i posveti ih meni za svećenike."},{"v":31,"t":"Onda kaži Izraelcima ovako: 'Ovo je moje posvećeno ulje za pomazanje od koljena do koljena."},{"v":32,"t":"Ne smije se polijevati po tijelu običnoga čovjeka; ne smijete praviti drugoga ovakva sastava! To je posvećeno i neka vam bude sveto!"},{"v":33,"t":"Tko god takvo napravi, ili tko ga stavi na kojeg svjetovnjaka, neka se odstrani od svog naroda!'”"},{"v":34,"t":"Jahve još reče Mojsiju: “Nabavi mirodija: natafe, šeheleta i helebene. Od ovih mirodija i čistoga tamjana,"},{"v":35,"t":"sve u jednakim dijelovima, napravi tamjan za kađenje, smjesu mirodija kakvu pravi pomastar, opranu, čistu, svetu."},{"v":36,"t":"Od toga nešto smrvi u prah i jedan dio stavi pred Svjedočanstvo, u Šator sastanka, gdje ću se ja s tobom sastajati. Držite ovu mirodiju presvetom!"},{"v":37,"t":"A miomiris koji napraviš prema ovome sastavu za svoju upotrebu ne smijete praviti. To drži za svetinju Jahvi!"},{"v":38,"t":"Tko sebi napravi što takvo da mu miriše, neka se iskorijeni iz svoga naroda.”"}]},"31":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Pozvao sam, gledaj, po imenu Besalela, sina Urijeva, od koljena Hurova iz plemena Judina."},{"v":3,"t":"Napunio sam ga duhom Božjim koji mu je dao umješnost, razumijevanje i sposobnost za svakovrsne poslove:"},{"v":4,"t":"da zamišlja nacrte za radove od zlata, srebra i tuča;"},{"v":5,"t":"za rezanje dragulja, za umetanje; za rezbarije u drvu i poslove svakakve."},{"v":6,"t":"Dodao sam još Oholiaba, sina Ahisamakova iz Danova plemena; vještinom sam obdario sve sposobne ljude da mognu napraviti sve što sam ti naredio:"},{"v":7,"t":"Šator sastanka, Kovčeg Svjedočanstva, povrh njega Pomirilište i sav namještaj Šatora;"},{"v":8,"t":"stol i sav njegov pribor, čisti svijećnjak sa svim njegovim priborom;"},{"v":9,"t":"kadioni žrtvenik, žrtvenik za žrtve paljenice i njegov pribor, onda umivaonik i njegovo podnožje;"},{"v":10,"t":"odijela za službu, posvećena odijela za svećenika Arona i odijela za njegove sinove, za njihovu svećeničku službu;"},{"v":11,"t":"pa ulje za pomazanje i miomirisni tamjan za Svetište. Sve neka načine kako sam ti naredio.”"},{"v":12,"t":"Jahve opet reče Mojsiju:"},{"v":13,"t":"“Reci Izraelcima: Subote moje morate održavati, jer subota je znak između mene i vas od naraštaja do naraštaja, da budete svjesni da vas ja, Jahve, posvećujem."},{"v":14,"t":"Držite, dakle, subotu, jer je ona za vas sveta. Tko je oskvrne neka se pogubi; tko bude u njoj radio ikakav posao neka se odstrani iz svoga naroda."},{"v":15,"t":"Šest dana neka se vrše poslovi, ali sedmi dan neka bude dan posvemašnjeg odmora, Jahvi posvećen. Tko bi u dan subotni obavljao kakav posao neka se pogubi."},{"v":16,"t":"Stoga neka Izraelci drže subotu - svetkujući je od naraštaja do naraštaja - kao vječni savez."},{"v":17,"t":"Neka je ona znak, zauvijek, između mene i Izraelaca. TÓa Jahve je za šest dana sazdao nebo i zemlju, a sedmoga je dana prestao raditi i odahnuo.”"},{"v":18,"t":"Kad Jahve svrši svoj razgovor s Mojsijem na Sinajskom brdu, dade mu dvije ploče Svjedočanstva, ploče kamene, ispisane prstom Božjim."}]},"32":{"hr":[{"v":1,"t":"A narod, videći gdje Mojsije dugo ne silazi s brda, okupi se oko Arona pa mu rekne: “Ustaj! Napravi nam boga, pa neka on pred nama ide! Ne znamo što se dogodi s tim čovjekom Mojsijem koji nas izvede iz zemlje egipatske.”"},{"v":2,"t":"“Poskidajte zlatne naušnice što vise o ušima vaših žena, vaših sinova i vaših kćeri”, odgovori im Aron, “pa ih meni donesite.”"},{"v":3,"t":"Sav svijet skine zlatne naušnice što ih je o ušima imao i donese Aronu."},{"v":4,"t":"Primivši zlato iz njihovih ruku, rastopi kovinu u kalupu i načini saliveno tele. A oni poviču: “Ovo je tvoj bog, Izraele, koji te izveo iz zemlje egipatske.”"},{"v":5,"t":"Vidjevši to Aron, sagradi pred njim žrtvenik a onda najavi: “Sutra neka se priredi svečanost u čast Jahvi!”"},{"v":6,"t":"Sutradan rano ustanu i prinesu žrtve paljenice i donesu žrtve pričesnice. Onda svijet posjeda da jede i pije. Poslije toga ustade da se zabavlja."},{"v":7,"t":"“Požuri se dolje!” - progovori Jahve Mojsiju. “Narod tvoj, koji si izveo iz zemlje egipatske, pošao je naopako."},{"v":8,"t":"Brzo su zašli s puta koji sam im odredio. Napravili su sebi tele od rastopljene kovine, preda nj pali ničice i žrtve mu prinijeli uz poklike: 'Ovo je tvoj bog, Izraele, koji te izveo iz zemlje egipatske!'"},{"v":9,"t":"Dobro vidim”, reče dalje Jahve Mojsiju, “da je ovaj narod tvrde šije."},{"v":10,"t":"Pusti sada neka se moj gnjev na njih raspali da ih istrijebim. Onda ću od tebe razviti velik narod.”"},{"v":11,"t":"Mojsije pak zapomagao pred Jahvom, Bogom svojim, i govorio: “O Jahve! Čemu da gnjevom plamtiš na svoj narod koji si izbavio iz zemlje egipatske silom velikom i rukom jakom!"},{"v":12,"t":"Zašto bi Egipćani morali reći: 'U zloj ih je namjeri i odveo, tako da ih smakne u brdinama i izbriše s lica zemlje!' Smiri svoj gnjev i ljutinu; odustani od zla svome narodu!"},{"v":13,"t":"Sjeti se Abrahama, Izaka i Izraela, slugu svojih, kojima si se samim sobom zakleo i obećao im: 'Razmnožit ću vaše potomstvo kao zvijezde na nebu i svu zemlju ovu što sam obećao dat ću vašem potomstvu i ona će zavazda biti njihova baština.'”"},{"v":14,"t":"I Jahve odustane da na svoj narod svali nesreću kojom mu bijaše zaprijetio."},{"v":15,"t":"Mojsije se okrene i siđe s brda. U rukama su mu bile dvije ploče Svjedočanstva, ploče ispisane na objema plohama; ispisane i s jedne i s druge strane."},{"v":16,"t":"Ploče su bile djelo Božje; pismo je bilo pismo Božje u pločama urezano."},{"v":17,"t":"A Jošua ču viku naroda koji je bučio pa reče Mojsiju: “Bojna vika u taboru!”"},{"v":18,"t":"Mojsije mu odgovori: “Niti viču pobjednici, niti tuže pobijeđeni: tu ja samo pjesmu čujem.”"},{"v":19,"t":"Čim se približi taboru te opazi tele i kako igraju, razgnjevi se Mojsije. Baci iz ruku ploče i razbije ih na podnožju brda."},{"v":20,"t":"Pograbi tele koje bijahu napravili, spali ga ognjem i u prah satre. Onda prah razbaca po vodi i natjera Izraelce da je piju."},{"v":21,"t":"“Što ti je ovaj puk učinio”, reče Mojsije Aronu, “da si tako velik grijeh na nj svalio?”"},{"v":22,"t":"“Neka se moj gospodar srdžbom ne raspaljuje”, odgovori Aron. “Sam dobro znaš kako je ovaj narod na zlo sklon."},{"v":23,"t":"Rekoše mi: 'Napravi nam boga pa neka pred nama ide! Ne znamo što se dogodi s tim čovjekom Mojsijem koji nas izbavi iz zemlje egipatske.'"},{"v":24,"t":"Na to im ja rekoh: 'Tko ima zlata, neka ga skine!' Tako mi ga dadoše, a ja ga bacih u vatru te izađe ovo tele.”"},{"v":25,"t":"Kad je Mojsije vidio kako je narod postao razuzdan - tÓa Aron ih je pustio da padnu u idolopoklonstvo među svojim neprijateljima -"},{"v":26,"t":"stade na taborskim vratima i povika: “Tko je za Jahvu, k meni!” Svi se sinovi Levijevi okupe oko njega."},{"v":27,"t":"On im reče: “Ovako govori Jahve, Bog Izraela: 'Neka svatko pripaše mač o bedro i pođe taborom od vrata do vrata pa neka ubije tko svoga brata, tko svoga prijatelja, tko svoga susjeda.'”"},{"v":28,"t":"Sinovi Levijevi izvršiše Mojsijev nalog, i toga dana pade naroda oko tri tisuće ljudi."},{"v":29,"t":"“Danas ste se posvetili Jahvi za službu”, reče Mojsije, “tko uz cijenu svoga sina, tko uz cijenu svoga brata, tako da vam danas daje blagoslov.”"},{"v":30,"t":"Sutradan reče Mojsije narodu: “Težak ste grijeh počinili. Ipak ću se Jahvi popeti. Možda za vaš grijeh oproštenje pribavim.”"},{"v":31,"t":"Mojsije se vrati Jahvi pa reče: “Jao! Narod onaj težak je grijeh počinio napravivši sebi boga od zlata."},{"v":32,"t":"Ipak im taj grijeh oprosti... Ako nećeš, onda i mene izbriši iz svoje knjige koju si napisao.”"},{"v":33,"t":"Nato Jahve odgovori Mojsiju: “Onoga koji je protiv mene sagriješio izbrisat ću iz svoje knjige."},{"v":34,"t":"Nego, idi sad! Povedi narod kamo sam ti rekao. Anđeo će moj pred tobom ići. Ali u dan kad ih pohodim, zbog njihova ću ih grijeha kazniti.”"},{"v":35,"t":"Udari Jahve po narodu pomorom zbog teleta što im ga Aron načini."}]},"33":{"hr":[{"v":1,"t":"Jahve reče Mojsiju: “Idi! Putuj odavde, ti i narod koji si izveo iz zemlje egipatske, u zemlju za koju sam se zakleo Abrahamu, Izaku i Jakovu da ću je dati njihovim potomcima."},{"v":2,"t":"Pred tobom ću poslati anđela; istjerat ću Kanaance, Amorejce, Hetite, Perižane, Hivijce i Jebusejce."},{"v":3,"t":"Idite u zemlju kojom teče mlijeko i med. Ja s vama neću poći - jer ste narod tvrde šije - da vas putem ne istrijebim.”"},{"v":4,"t":"Kad narod ču ove oštre riječi, poče tugovati. I nitko više ne stavi na se svoga nakita."},{"v":5,"t":"Jer reče Jahve Mojsiju: “Kaži Izraelcima: 'Vi ste narod tvrde šije. Kad bih ja s vama išao samo čas, uništio bih vas. Stoga skinite svoj nakit, a ja ću vidjeti što ću s vama učiniti.'”"},{"v":6,"t":"Tako su od brda Horeba Izraelci bili bez nakita."},{"v":7,"t":"Mojsije uze Šator i razape ga izvan tabora, daleko od tabora. I nazva ga Šator sastanka. Tko bi se god htio obratiti Jahvi, pošao bi k Šatoru sastanka, koji se nalazio izvan tabora."},{"v":8,"t":"Kad bi god Mojsije pošao u Šator, sav bi se narod digao; svatko bi stajao kod ulaza u svoj šator i gledao za Mojsijem dok ne bi ušao u Šator."},{"v":9,"t":"A kad bi Mojsije ušao u Šator, stup bi se oblaka spustio i ostajao na ulazu u Šator dok je Jahve s Mojsijem razgovarao."},{"v":10,"t":"Videći kako stup oblaka stoji na ulazu Šatora, sav bi se narod tada dizao i svatko bi se duboko klanjao na vratima svoga šatora."},{"v":11,"t":"Tako bi Jahve razgovarao s Mojsijem licem u lice, kao što čovjek govori s prijateljem. Mojsije bi se poslije vratio u tabor, ali se njegov pomoćnik Jošua, sin Nunov, mlađarac, iz Šatora ne bi micao."},{"v":12,"t":"Mojsije oslovi Jahvu: “Vidi, ti si meni rekao: 'Povedi ovaj narod', ali mi nisi objavio koga ćeš sa mnom poslati. Još si mi rekao: 'Znam te po imenu, i ti uživaš moju blagonaklonost.'"},{"v":13,"t":"Stoga, ako uživam tvoju blagonaklonost, objavi mi svoje putove da te shvatim i da dalje uživam tvoju blagonaklonost. Promisli također da je ova svjetina tvoj narod.”"},{"v":14,"t":"“Ja ću osobno s tobom poći”, odgovori Jahve, “i počinak ti priuštiti.”"},{"v":15,"t":"“Ako ti ne pođeš”, nadoda Mojsije, “odavde nas i ne izvodi."},{"v":16,"t":"TÓa kako će se znati da uživamo tvoju naklonost, ja i tvoj narod? Po tome što ideš s nama. Time ćemo se samo razlikovati ja i tvoj narod među svim narodima koji su na licu zemlje.”"},{"v":17,"t":"“I ovo što si zatražio, učinit ću”, odgovori Jahve Mojsiju. “TÓa ti uživaš moju blagonaklonost jer te po imenu poznajem.”"},{"v":18,"t":"“Pokaži mi svoju slavu”, zamoli Mojsije."},{"v":19,"t":"“Dopustit ću da ispred tebe prođe sav moj sjaj”, odgovori, “i pred tobom ću izustiti svoje ime Jahve. Bit ću milostiv kome hoću da milostiv budem; smilovat ću se komu hoću da se smilujem."},{"v":20,"t":"A ti”, doda, “moga lica ne možeš vidjeti, jer ne može čovjek mene vidjeti i na životu ostati."},{"v":21,"t":"Evo mjesta ovdje uza me”, nastavi Jahve. “Stani na pećinu!"},{"v":22,"t":"Dok moja slava bude prolazila, stavit ću te u pukotinu pećine i svojom te rukom zakloniti dok ne prođem."},{"v":23,"t":"Onda ću ja svoju ruku maknuti, pa ćeš me s leđa vidjeti. Ali se lice moje ne može vidjeti.”"}]},"34":{"hr":[{"v":1,"t":"Reče Jahve Mojsiju: “Okleši dvije kamene ploče kao i prijašnje pa ću ja na ploče napisati riječi koje su bile na prvim pločama što si ih razbio."},{"v":2,"t":"Budi gotov do jutra. Onda, ujutro, popni se na brdo Sinaj i ondje ćeš, navrh brda, stupiti preda me."},{"v":3,"t":"Nitko drugi neka se s tobom ne penje; neka se nitko nigdje na brdu ne pokaže. Neka ni ovce ni goveda ne pasu podno brda.”"},{"v":4,"t":"Mojsije okleše dvije kamene ploče kao i prijašnje; rano jutrom ustane i popne se na Sinajsko brdo, uzevši u ruke dvije kamene ploče, kako mu je Jahve naredio."},{"v":5,"t":"Jahve se spusti u liku oblaka, a on stade preda nj i zazva Ime: “Jahve!”"},{"v":6,"t":"Jahve prođe ispred njega te se javi: “Jahve! Jahve! Bog milosrdan i milostiv, spor na srdžbu, bogat ljubavlju i vjernošću,"},{"v":7,"t":"iskazuje milost tisućama, podnosi opačinu, grijeh i prijestup, ali krivca nekažnjena ne ostavlja nego kažnjava opačinu otaca na djeci - čak na unučadi do trećega i četvrtog koljena.”"},{"v":8,"t":"Mojsije smjesta pade na zemlju i pokloni se."},{"v":9,"t":"Onda reče: “Gospodine moj! Ako sam stekao blagonaklonost u tvojim očima, onda, o Gospodine, pođi s nama! Premda je narod tvrde šije, oprosti naše grijehe i naše opačine i primi nas za svoju baštinu!”"},{"v":10,"t":"“Dobro”, odgovori, “sklapam Savez. Pred cijelim tvojim pukom činit ću čudesa kakva se nisu događala ni u kojoj zemlji, ni u kojem narodu. Sav narod koji te okružuje vidjet će što može Jahve, jer ono što ću s tobom učiniti bit će strašno."},{"v":11,"t":"Vrši, dakle, što ti danas nalažem! Gle, protjerat će ispred tebe Amorejce, Kanaance, Hetite, Perižane, Hivijce i Jebusejce."},{"v":12,"t":"Čuvaj se da ne praviš saveza sa stanovnicima zemlje u koju ideš; da ne budu zamkom u tvojoj sredini."},{"v":13,"t":"Nego porušite njihove žrtvenike, oborite njihove stupove, počupajte im ašere!"},{"v":14,"t":"Jer ne smiješ se klanjati drugome bogu. TÓa Jahve - ime mu je Ljubomorni - Bog je ljubomoran."},{"v":15,"t":"Ne pravi saveza sa stanovnicima one zemlje da te oni, kad se odaju bludnosti sa svojim bogovima i žrtve im budu prinosili, ne bi pozivali, a ti pristao da jedeš od prinesene žrtve;"},{"v":16,"t":"da ne bi uzimao njihove djevojke za žene svojim sinovima, da one - odajući se bludništvu sa svojim bogovima - ne bi za sobom povele i tvoje sinove."},{"v":17,"t":"Ne pravi sebi livenih bogova!"},{"v":18,"t":"Drži Blagdan beskvasnoga kruha - jedući beskvasni kruh sedam dana, kako sam ti naredio - u određeno vrijeme u mjesecu Abibu, jer si u mjesecu Abibu izišao iz Egipta."},{"v":19,"t":"Svako prvorođenče materinjega krila meni pripada: svako muško, svaki prvenac tvoga i sitnoga i krupnoga blaga."},{"v":20,"t":"Prvenca od magarice otkupi jednim grlom sitne stoke. Ako ga ne otkupiš, moraš mu šijom zavrnuti. A sve prvorođence od svojih sinova otkupljuj. Neka nitko preda me ne stupa praznih ruku!"},{"v":21,"t":"Šest dana radi, a sedmoga od poslova odustani, sve ako je u doba oranja ili u vrijeme žetve."},{"v":22,"t":"Svetkuj Blagdan sedmica - prvine pšenične žetve - i Blagdan berbe na prekretu godine."},{"v":23,"t":"Triput na godinu neka se svi muškarci pojave pred Gospodinom Jahvom, Bogom Izraelovim."},{"v":24,"t":"Jer ću protjerati narode ispred tebe i proširiti tvoje međe te nitko neće hlepiti za tvojom zemljom kad triput u godini budeš uzlazio da se pokažeš pred Jahvom, Bogom svojim."},{"v":25,"t":"Od žrtve koju mi namjenjuješ ne prinosi krvi ni s čim ukvasanim; niti ostavljaj žrtve prinesene na blagdan Pashe da prenoći do jutra."},{"v":26,"t":"U kuću Jahve, Boga svoga, donosi najbolje prvine plodova sa svoje zemlje. Ne kuhaj kozleta u mlijeku njegove majke."},{"v":27,"t":"Zapiši ove riječi”, reče Jahve Mojsiju, “jer su one temelji na kojima sam s tobom i s Izraelom sklopio Savez.”"},{"v":28,"t":"Mojsije ostade ondje s Jahvom četrdeset dana i četrdeset noći. Niti je kruha jeo niti je vode pio. Tada je na ploče ispisao riječi Saveza - Deset zapovijedi."},{"v":29,"t":"Napokon Mojsije siđe sa Sinajskog brda. Silazeći s brda, nosio je u rukama ploče Svjedočanstva. Nije ni znao da iz njegova lica, zbog razgovora s Jahvom, izbija svjetlost."},{"v":30,"t":"Kad su Aron i svi Izraelci vidjeli kako iz Mojsijeva lica izbija svjetlost, ne usudiše se k njemu pristupiti."},{"v":31,"t":"Onda ih Mojsije zovnu. Tada k njemu dođoše Aron i sve starješine zajednice. I Mojsije razgovaraše s njima."},{"v":32,"t":"Poslije k njemu dođoše i svi Izraelci, pa im on priopći sve što mu je naložio Jahve na Sinajskom brdu."},{"v":33,"t":"Kad je Mojsije završio razgovor s njima, prevuče preko svoga lica koprenu."},{"v":34,"t":"Kad bi god Mojsije ulazio pred Jahvu da s njim razgovara, koprenu bi skinuo dok opet ne bi izišao. Kad bi izlazio da Izraelcima kaže što mu je naređeno,"},{"v":35,"t":"Izraelci bi vidjeli kako iz Mojsijeva lica izbija svjetlost. Tada bi Mojsije opet prevukao koprenu preko lica dok ne uđe da s Jahvom govori."}]},"35":{"hr":[{"v":1,"t":"Mojsije sazva svu zajednicu sinova Izraelovih pa im reče: “Ovo vam je Jahve naložio da činite:"},{"v":2,"t":"Neka se posao obavlja šest dana. Sedmi dan neka vam bude sveti dan, dan potpunog počinka u čast Jahvi. Tko bi radio u taj dan neka se kazni smrću."},{"v":3,"t":"Na subotnji dan ni vatre ne ložite po svojim stanovima.”"},{"v":4,"t":"Nadalje Mojsije reče svoj zajednici izraelskoj: “Ovo je Jahve naredio:"},{"v":5,"t":"Među sobom pokupite prinos Jahvi! Tko god je plemenita srca neka Jahvi donese prinos: zlata, srebra i tuča;"},{"v":6,"t":"ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana;"},{"v":7,"t":"učinjenih ovnujskih koža, onda finih koža, bagremova drva,"},{"v":8,"t":"ulja za svjetlo, mirodija za ulje pomazanja i miomirisni tamjan;"},{"v":9,"t":"oniksa i drugoga dragog kamenja za umetanje u oplećak i naprsnik."},{"v":10,"t":"A svi koji su među vama vješti neka dođu praviti što je Jahve naredio:"},{"v":11,"t":"Prebivalište, njegov Šator i pokrov; njegove kuke i trenice, njegove priječnice i stupce; njegova podnožja;"},{"v":12,"t":"njegov Kovčeg i motke; Pomirilište pa zavjesu za zaklon;"},{"v":13,"t":"stol s njegovim motkama i sve njegove potrepštine; prinesene hljebove;"},{"v":14,"t":"svijećnjak za svjetlo, njegov pribor i njegove svijeće, onda ulje za svjetlo;"},{"v":15,"t":"kadioni žrtvenik i njegove motke; ulje za pomazanje i miomirisni tamjan; zastorak na ulazu u Prebivalište;"},{"v":16,"t":"žrtvenik za žrtve paljenice s njegovom rešetkom od tuča; motke za nj i sav njegov pribor; umivaonik i njegov stalak;"},{"v":17,"t":"zastore za dvorište; stupce i njihova podnožja, pa zastor na ulazu u dvorište;"},{"v":18,"t":"kočiće za Prebivalište i kočiće za dvorište s njihovim uzicama;"},{"v":19,"t":"svečano ruho za vršenje službe u Svetištu - posvećena odijela za svećenika Arona i odijela za svećeničku službu njegovih sinova.”"},{"v":20,"t":"Nato se sva izraelska zajednica povuče ispred Mojsija."},{"v":21,"t":"A onda svatko koga je srce vuklo i duša poticala dođe noseći svoj prinos u čast Jahvi za gradnju Šatora sastanka, za svaku službu u njemu i za posvećena odijela."},{"v":22,"t":"Strčaše se muževi i žene: svi koje je srce vuklo donesoše zapinjača, naušnica, prstenja, narukvica, ogrlica i svakovrsna zlatnog nakita; svi koji bijahu zavjetovali kakvu zlatninu u čast Jahvi."},{"v":23,"t":"Svi kod kojih se našlo ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana, učinjenih ovnujskih koža ili finih koža donesoše svoje."},{"v":24,"t":"Nadalje, svatko tko je mogao dati kakav dar u srebru ili tuču donese to kao prinos u čast Jahvi. Svatko u koga se našlo bagremova drva za upotrebu u bilo kojem poslu, donese ga."},{"v":25,"t":"Sve žene koje su bile vješte prele su svojim rukama i donosile što bijahu oprele: ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana."},{"v":26,"t":"Sve opet žene koje je njihovo srce poticalo zbog njihove vještine prele su kostrijet."},{"v":27,"t":"Glavari su donosili oniksa i drugoga dragog kamenja za umetanje u oplećak i naprsnik;"},{"v":28,"t":"pa mirodije i ulje za svjetlo, ulje za pomazanje i miomirisni tamjan."},{"v":29,"t":"I tako Izraelci - svi ljudi i sve žene koje je srce poticalo da pridonesu bilo što poslu koji je Jahve po Mojsiju naredio da se izvrši - donesoše to kao dragovoljan prinos u čast Jahvi."},{"v":30,"t":"Potom reče Mojsije Izraelcima: “Vidite! Jahve je po imenu pozvao Besalela, sina Urijeva, od koljena Hurova a iz plemena Judina."},{"v":31,"t":"Njega je napunio duhom Božjim, dao mu umješnost, sposobnost i razumijevanje u svim poslovima:"},{"v":32,"t":"da zamišlja nacrte i da radove izvodi od zlata, srebra i tuča;"},{"v":33,"t":"da reže dragulje za umetanje; da urezuje u drvetu i da umješno radi svaki posao."},{"v":34,"t":"Njemu i Oholiabu, sinu Ahisamakovu, od plemena Danova, udijeli i sposobnost da poučavaju druge."},{"v":35,"t":"Obdari ih umještvom u svakom poslu rezbarskom, krojačkom, veziljskom i tkalačkom; oni tkaju tkanine od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana, sposobni su u svakom poslu i vješti u nacrtima."}]},"36":{"hr":[{"v":1,"t":"Stoga neka Besalel, Oholiab i svi vještaci koje je Jahve obdario vještinom i sposobnošću da vješto izvedu sve poslove oko podizanja Svetišta obave sve kako je Jahve naredio.”"},{"v":2,"t":"Mojsije onda pozva Besalela, Oholiaba i sve one što ih je Jahve obdario vještinom; sve koje je srce poticalo da se prihvate posla i izvedu ga."},{"v":3,"t":"Oni preuzmu od Mojsija sve prinose koje Izraelci bijahu donijeli da se izvedu poslovi oko podizanja Svetišta. Ali kako su oni i dalje donosili prinose jutro za jutrom,"},{"v":4,"t":"svi majstori koji su gradili Svetište dođu - svaki s posla na kojem je radio -"},{"v":5,"t":"i reknu Mojsiju: “Svijet donosi mnogo više nego što je potrebno za izvođenje posla koji nam je Jahve naredio da izvedemo.”"},{"v":6,"t":"Zato Mojsije izda naredbu koju po taboru proglase: “Neka više nijedan čovjek ni žena ne donosi nikakva priloga za Svetište!” Tako ustave narod te nije donosio novih darova."},{"v":7,"t":"Što imahu bijaše dosta da se izvede sve djelo; i još je pretjecalo."},{"v":8,"t":"I tako najvještiji ljudi među radnicima naprave Prebivalište. Načine ga od deset zavjesa od prepredenog lana i ljubičastog, crvenog i tamnocrvenog prediva. Na njima bijahu izvezeni likovi kerubina."},{"v":9,"t":"Dužina je svake zavjese iznosila dvadeset osam lakata, a širina svake zavjese četiri lakta. Sve su zavjese bile iste mjere."},{"v":10,"t":"Pet zavjesa sastave jednu s drugom, a pet drugih zavjesa sastave opet jednu s drugom."},{"v":11,"t":"Na rubu posljednje od zavjesa sastavljenih u jedno načine petlje od modre vune; jednako ih načine i na rubu posljednje zavjese drugoga dijela;"},{"v":12,"t":"načine pedeset petlji na jednome komadu, a pedeset na rubu zavjese drugoga komada. Petlje su stajale jedna spram druge."},{"v":13,"t":"Onda naprave pedeset zlatnih kopča pa sastave zavjese kopčama jednu s drugom. Tako je Prebivalište bilo kao jedna cjelina."},{"v":14,"t":"Zatim za Šator povrh Prebivališta načine zavjese od kostrijeti; načine ih jedanaest."},{"v":15,"t":"Dužina svake zavjese bila je trideset lakata, a širina četiri lakta. Tih jedanaest zavjesa bilo je iste mjere."},{"v":16,"t":"Sastave pet zavjesa za se, a šest drugih opet za se."},{"v":17,"t":"Naprave pedeset petlji na rubu zavjese jednoga komada, a pedeset načine na rubu drugoga komada."},{"v":18,"t":"Načine i pedeset kopča od tuča da sastave Šator zajedno, tako da bude jedna cjelina."},{"v":19,"t":"Zatim naprave pokrov za Šator od učinjenih ovnujskih koža, a povrh njega drugi, od finih koža."},{"v":20,"t":"Trenice nauzgor za Prebivalište izrade od bagremova drva."},{"v":21,"t":"Duljina je svake trenice bila deset lakata, a širina lakat i pol."},{"v":22,"t":"Svaka je trenica imala dva klina da je drže uspravno. To su napravili na svakoj trenici za Šator."},{"v":23,"t":"Trenice za Prebivalište napravili su ovako: dvadeset trenica za južnu stranu;"},{"v":24,"t":"napravili su četrdeset podnožja od srebra pod dvadeset trenica - dva podnožja pod prvu trenicu za njezina dva klina i dva podnožja pod svaku slijedeću trenicu za njezina dva klina."},{"v":25,"t":"Za drugu, sjevernu, stranu Prebivališta naprave dvadeset trenica"},{"v":26,"t":"i za njih četrdeset podnožja od srebra - dva podnožja pod prvu trenicu, a po dva podnožja pod svaku slijedeću trenicu."},{"v":27,"t":"Prebivalištu straga, prema zapadu, napraviše šest trenica."},{"v":28,"t":"Naprave i dvije trenice za uglove Prebivališta straga."},{"v":29,"t":"Pri dnu su bile rastavljene, ali su se pri vrhu, kod prvoga koluta, sastajale. Tako su ih obje postavili za dva ugla."},{"v":30,"t":"Bilo je osam trenica s njihovim podnožjima od srebra: šesnaest podnožja, pod svakom trenicom dva."},{"v":31,"t":"Načine priječnice od bagremova drva: pet njih za trenice s jedne strane Prebivališta,"},{"v":32,"t":"a pet opet priječnica za trenice s druge strane Prebivališta te pet priječnica za trenice Prebivalištu straga, prema zapadu."},{"v":33,"t":"Onda načine središnju priječnicu što je prolazila sredinom trenica s kraja na kraj."},{"v":34,"t":"Trenice oblože zlatom, a njihove kolutove, kroz koje su priječnice bile provučene, načine od zlata. I priječnice oblože zlatom."},{"v":35,"t":"Naprave zavjesu od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana; načine je s izvezenim kerubinima."},{"v":36,"t":"Za nju naprave četiri stupa od bagremova drva i oblože ih zlatom. Kuke su im bile od zlata, a saliju im i četiri podnožja od srebra."},{"v":37,"t":"Na ulazu u Šator naprave zavjesu od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana, umjetnički protkanu,"},{"v":38,"t":"i za nju pet stupčića s njihovim kukama. Vrhove stupčića i njihove šipke oblože zlatom, dok im pet podnožja naprave od tuča."}]},"37":{"hr":[{"v":1,"t":"Besalel napravi Kovčeg od bagremova drva, dug dva i pol lakta, širok lakat i pol, a lakat i pol visok."},{"v":2,"t":"Iznutra ga i izvana okuje čistim zlatom. Naokolo mu napravi zlatan završni pojas."},{"v":3,"t":"I salije mu četiri koluta na njegova četiri ugla: dva koluta s jedne strane, a dva koluta s njegove druge strane."},{"v":4,"t":"Napravi i motke od bagremova drva i u zlato ih okuje;"},{"v":5,"t":"onda provuče motke kroz kolutove Kovčegu sa strane za nošenje Kovčega."},{"v":6,"t":"Zatim napravi Pomirilište od čistoga zlata, dva i pol lakta dugo, a lakat i pol široko."},{"v":7,"t":"Napravi i dva kerubina od kovanoga zlata, na dva kraja Pomirilišta:"},{"v":8,"t":"jednoga kerubina na jednome kraju, a drugoga kerubina na drugome kraju. Kerubine na oba kraja načini u jednome komadu s Pomirilištem."},{"v":9,"t":"Kerubini imali uzdignuta i raširena krila, zaklanjali njima Pomirilište. Bili su licem okrenuti jedan prema drugome, tako da su im lica gledala u Pomirilište."},{"v":10,"t":"Od bagremova drva načini stol, dva lakta dug, lakat širok, a lakat i pol visok."},{"v":11,"t":"Obloži ga čistim zlatom i od zlata mu naokolo načini završni pojas."},{"v":12,"t":"I načini mu obrub unaokolo, podlanicu širok. A za obrub naokolo načini zlatan završni pojas."},{"v":13,"t":"Salije mu četiri zlatna koluta. Kolutove onda pričvrsti za njegova četiri nožna ugla."},{"v":14,"t":"Kolutovi su bili tik pod obrubom, kao kvake za motke, da se stol može nositi."},{"v":15,"t":"Motke za nošenje stola načinio je od bagremova drva i zlatom ih obložio."},{"v":16,"t":"A pribor što se držao na stolu - njegove zdjele, varjače, vrčeve i pehare za izlijevanje prinosa - napravio je od čistoga zlata."},{"v":17,"t":"Od čistoga zlata načini i svijećnjak. Svijećnjak - njegovo podnožje i stalak - skova. Njegove čaše - čaške i latice - bile su u jednome komadu s njim."},{"v":18,"t":"Šest je krakova izbijalo s njegovih strana: tri kraka svijećnjaka s jedne strane, a tri kraka svijećnjaka s druge strane."},{"v":19,"t":"Na jednome kraku bile su tri čaše u obliku bademova cvijeta, svaka sa svojom čaškom i laticama. Na drugome opet kraku bile su tri čaše u obliku bademova cvijeta, svaka s čaškom i laticama. Tako je bilo na svih šest krakova što izbijahu iz svijećnjaka."},{"v":20,"t":"Na samome svijećnjaku bile su četiri čaše u obliku bademova cvijeta, svaka s čaškom i laticama:"},{"v":21,"t":"čaška, u jednom komadu s njim, pod prva dva kraka; pa konačno čaška, u jednom komadu s njim, pod zadnja dva kraka. Tako na svih šest krakova što su iz njega izbijali."},{"v":22,"t":"Njihove čaške i njihove peteljke bile su u jednom komadu s njim; sve to od čistoga kovanog zlata."},{"v":23,"t":"A od čistoga zlata napravi mu i sedam svjetiljaka, usekače i pepeljare."},{"v":24,"t":"Svijećnjak i sav njegov pribor načini od jednoga talenta čistoga zlata."},{"v":25,"t":"Kadioni je žrtvenik napravio od bagremova drva, lakat dug, lakat širok - u četvorinu - a dva lakta visok. Roščići su mu bili u jednom komadu s njim."},{"v":26,"t":"Obloži mu čistim zlatom plohu, strane naokolo i njegove roščiće. Načini mu naokolo završni pojas od zlata."},{"v":27,"t":"Na njemu načini i dva zlatna koluta na oprečnim stranama, ispod završnog pojasa, da služe motkama za kvake kad se na njima nosi."},{"v":28,"t":"Motke načini od bagremova drva pa ih obloži zlatom."},{"v":29,"t":"Onda pripravi posvećeno ulje za pomazanje i čisti kad mirisni, onako kako ga pravi pomastar."}]},"38":{"hr":[{"v":1,"t":"Od bagremova drva napravi žrtvenik za žrtve paljenice, pet lakata dug, pet lakata širok - u četvorinu - a tri lakta visok."},{"v":2,"t":"Na njegova četiri ugla načini mu četiri roga. Rogovi su bili u jednom komadu s njim. Onda ga obloži tučem."},{"v":3,"t":"A načini i sav pribor za žrtvenik: lonce, strugače, kotliće, viljuške i kadionike; sav mu je ovaj pribor načinio od tuča."},{"v":4,"t":"Za žrtvenik zatim načini rešetku u obliku mrežice od tuča ispod izbočine; zahvaćala mu je do sredine."},{"v":5,"t":"Salije četiri koluta na četiri ugla tučane rešetke da služe kao kvake za motke."},{"v":6,"t":"Motke načini od bagremova drva pa ih obloži tučem."},{"v":7,"t":"Onda provuče motke kroz kolutove na objema stranama žrtvenika da se na njima nosi. Napravio ga je šuplja - od dasaka."},{"v":8,"t":"A zatim, od zrcala žena koje su posluživale na vratima Šatora sastanka, načini tučani umivaonik i tučani stalak za nj."},{"v":9,"t":"Onda načini dvorište. Na južnoj strani dvorišta bijahu zavjese od prepredenog lana, stotinu lakata duge."},{"v":10,"t":"Njihovih dvadeset stupova sa dvadeset podnožja bilo je od tuča, dok su kuke na stupovima i njihove šipke bile od srebra."},{"v":11,"t":"Od stotinu lakata bile su zavjese i sa sjeverne strane. Njihovih dvadeset stupova sa dvadeset podnožja bilo je od tuča, dok su kuke na stupovima i njihove šipke bile od srebra."},{"v":12,"t":"Sa zapadne strane bijahu zavjese od pedeset lakata, sa deset stupova i deset njihovih podnožja. Kuke su na stupovima i njihove šipke bile od srebra."},{"v":13,"t":"Sprijeda, s istoka, zavjese od pedeset lakata."},{"v":14,"t":"S jedne strane vrata zavjese su bile petnaest lakata, sa tri stupca i njihova tri podnožja."},{"v":15,"t":"Tako i s druge strane - dakle, na obje strane dvorišnih vrata - bile su zavjese od petnaest lakata, sa tri stupca i njihova tri podnožja."},{"v":16,"t":"Sve su zavjese oko dvorišta bile od prepredenog lana."},{"v":17,"t":"Podnožja za stupove bila su od tuča, a kuke na stupovima i njihove šipke od srebra. Vrhovi stupova bili su srebrom obloženi. Sve šipke na dvorišnim stupovima bijahu od srebra."},{"v":18,"t":"Zavjesa na dvorišnim vratima - izvezena - bila je od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana. Dvadeset je lakata bila duga; visoka, po širini, pet lakata kao i dvorišne zavjese."},{"v":19,"t":"Bila su četiri njihova stupa sa četiri podnožja od tuča. Kuke na stupovima bile su od srebra. Vrhovi stupova bili su srebrom obloženi, a njihove šipke bile su srebrne."},{"v":20,"t":"Svi kočići unutar Prebivališta bili su od tuča."},{"v":21,"t":"To je popis stvari za Prebivalište - Prebivalište Svjedočanstva, koji je sastavljen na zapovijed Mojsijevu trudom levita pod vodstvom Itamara, sina svećenika Arona."},{"v":22,"t":"Besalel, Urijev sin, iz koljena Hurova od plemena Judina napravio je sve što je Jahve Mojsiju naredio."},{"v":23,"t":"S njim je bio Oholiab, sin Ahisamakov, iz plemena Danova, rezbar, krojač i vezilac za ljubičasto, crveno i tamnocrveno predivo i prepredeni lan."},{"v":24,"t":"Sve zlato što je utrošeno u radove oko Svetišta - zlato posvećeno prinosom - iznosilo je: dvadeset i devet talenata i sedam stotina trideset šekela u hramskim šekelima."},{"v":25,"t":"A srebro, sabrano prigodom upisivanja zajednice -"},{"v":26,"t":"to jest beku po glavi, odnosno pola šekela prema hramskom šekelu, od svakoga koji je bio upisan, od dvadeset godina pa naprijed - iznosilo je: stotinu talenata i tisuću sedam stotina sedamdeset i pet šekela u hramskim šekelima. Bilo je upisanih: šest stotina tri tisuće i petsto pedeset."},{"v":27,"t":"Stotinu talenata srebra otišlo je za salijevanje podnožja Svetištu i zavjesi: sto podnožja od sto talenata - talenat za podnožje."},{"v":28,"t":"A od tisuću sedam stotina sedamdeset i pet šekela načinio je kuke za stupove, obložio njihove vrhove i napravio šipke za njih."},{"v":29,"t":"Tuč od žrtve prikaznice iznosio je sedamdeset talenata i dvije tisuće četiri stotine šekela."},{"v":30,"t":"Od njega je načinio: podnožja za ulaz u Šator sastanka, žrtvenik od tuča s njegovom tučanom rešetkom i sav pribor za žrtvenik;"},{"v":31,"t":"dalje, podnožja oko dvorišta, podnožja za dvorišni ulaz; sve kočiće za Prebivalište i sve kočiće oko dvorišta."}]},"39":{"hr":[{"v":1,"t":"Od ljubičastog, crvenog i tamnocrvenog prediva naprave lijepo izrađeno ruho za službu u Svetištu; naprave svetu odjeću Aronu, kako je Jahve naredio Mojsiju."},{"v":2,"t":"Oplećak naprave od zlata, ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana."},{"v":3,"t":"Skuju zlatne pločice, a onda ih na niti izrežu da ih vještački uvezu u ljubičasto, crveno i tamnocrveno predivo i prepredeni lan."},{"v":4,"t":"Za oplećak naprave poramenice koje su bile s njim sastavljene na svoja dva kraja;"},{"v":5,"t":"tkanica što je na njemu stajala bila je napravljena od zlata, ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana kao i on, i u jednome komadu s njim, kako je Jahve naredio Mojsiju."},{"v":6,"t":"Kamenje oniksa optoče obrubom od zlata. Na njima su, kao što se režu pečati, bila urezana imena Izraelovih sinova."},{"v":7,"t":"Njih stave na poramenice oplećka da budu spomen-kamenje sinovima Izraelovim, kako je Jahve naredio Mojsiju."},{"v":8,"t":"I naprsnik izrade radovima vještaka kao i oplećak: od zlata, ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana."},{"v":9,"t":"Naprsnik načiniše četverouglast, dvostruk; bio je pedalj dug, pedalj širok, a predvostručen."},{"v":10,"t":"Umetnu u nj četiri reda dragulja. Prvi red bijaše od rubina, topaza i alema;"},{"v":11,"t":"drugi red od smaragda, safira i ametista;"},{"v":12,"t":"treći red od hijacinta, ahata i leca;"},{"v":13,"t":"a četvrti red od krizolita, oniksa i jaspisa. Sve je bilo zlatom obrubljeno."},{"v":14,"t":"Na kamenima su bila imena Izraelovih sinova. Na broj ih je bilo dvanaest, kao i njihovih imena. Bila su urezana kao i pečati - svaki kamen s imenom jednoga od dvanaest plemena."},{"v":15,"t":"Za naprsnik naprave lančiće od čistoga zlata kao zasukane uzice."},{"v":16,"t":"Naprave zatim dva zlatna okvira i dva zlatna kolutića pa pričvrste oba kolutića za dva gornja ugla naprsnika."},{"v":17,"t":"Sad privežu ovdje zasukane uzice od zlata za dva kolutića što su bila pričvšćena za uglove naprsnika."},{"v":18,"t":"Druga dva kraja zasukanih uzica pričvrste za dva okvira. Tako ih povežu za poramenice oplećka sprijeda."},{"v":19,"t":"Potom načine dva zlatna kolutića pa ih pričvrste za dva kraja naprsnika uz nutarnji rub, okrenut prema oplećku."},{"v":20,"t":"Još naprave dva zlatna kolutića te ih pričvrste za donji, prednji kraj poramenice oplećka, pokraj mjesta gdje se veže, povrh tkanice oplećka."},{"v":21,"t":"Svežu kolutiće naprsnika s kolutićima oplećka modrom vrpcom, tako da naprsnik stoji nad tkanicom oplećka i da se s oplećka ne mogne odvojiti, kako je Jahve Mojsiju naredio."},{"v":22,"t":"Naprave i ogrtač za oplećak, sav satkan od ljubičastog prediva."},{"v":23,"t":"U sredini je ogrtača bio prorez kao otvor na oklopu, prorez naokolo opšiven, da se ogrtač ne podere."},{"v":24,"t":"O donjem rubu ogrtača načine šipke od ljubičastog, crvenog i tamnocrvenog prediva i prepredenog lana."},{"v":25,"t":"A načine i zvonca od čistog zlata, pa zvonca privežu među šipke; sve naokolo donjeg ruba ogrtača između šipaka:"},{"v":26,"t":"zvonce pa šipak, zvonce pa šipak okolo donjeg ruba ogrtača za vršenje službe, kako je Jahve naredio Mojsiju."},{"v":27,"t":"Zatim od otkanog lana načine košulje Aronu i njegovim sinovima;"},{"v":28,"t":"a naprave i mitru od lana i kape od lana; platnene gaće načine od prepredenog lana."},{"v":29,"t":"I pasovi su bili od prepredenog lana i od ljubičastog, crvenog i tamnocrvenog prediva, iglama izvezeni, kako je Jahve Mojsiju naredio."},{"v":30,"t":"Načine i ploču, sveti vijenac, od čistoga zlata i na njoj urežu natpis kako se urezuje na pečatnome prstenu: “Posvećen Jahvi.”"},{"v":31,"t":"Za nju privežu modru vrpcu da je mogu svezati na vrhu mitre, kako je Jahve naredio Mojsiju."},{"v":32,"t":"Tako su bili završeni svi radovi na Prebivalištu, Šatoru sastanka. Izraelci su sve načinili onako kako je Jahve Mojsiju naredio da načine."},{"v":33,"t":"Onda donesu Mojsiju Prebivalište, Šator i sav njegov pribor: njegove kuke, njegove trenice, njegove priječnice, njegove stupove i njegova podnožja;"},{"v":34,"t":"pokrov od učinjenih ovnujskih koža, pokrov od finih koža, zavjesu za zaklon;"},{"v":35,"t":"Kovčeg svjedočanstva s njegovim motkama i Pomirilištem;"},{"v":36,"t":"stol i sav njegov pribor, prinesene hljebove,"},{"v":37,"t":"svijećnjak od čistoga zlata s njegovim svijećama - svijeće već u red stavljene - i sav njegov pribor i ulje za svjetlo;"},{"v":38,"t":"zlatni žrtvenik, ulje za pomazanje, miomirisni tamjan i zavjesu za ulaz Šatora;"},{"v":39,"t":"žrtvenik od tuča s tučanom rešetkom; njegove motke i sav njegov pribor; umivaonik i njegov stalak;"},{"v":40,"t":"zavjese za dvorište; njihove stupove i njihova podnožja, zavjesu za dvorišni ulaz, njegova užeta i njihove kočiće - sav pribor za službu u Prebivalištu, za Šator sastanka;"},{"v":41,"t":"lijepo izrađeno ruho za službu u Svetištu - svetu odjeću za svećenika Arona i odijela za svećeničku službu njegovih sinova."},{"v":42,"t":"Upravo kako je Jahve Mojsiju naredio, tako su Izraelci sav posao obavili."},{"v":43,"t":"Mojsije pregleda sve radove i utvrdi da su ih dovršili: kako je Jahve naredio, onako su ih i napravili. I Mojsije ih blagoslovi."}]},"40":{"hr":[{"v":1,"t":"Reče Jahve Mojsiju:"},{"v":2,"t":"“Na prvi dan prvoga mjeseca podigni Prebivalište, Šator sastanka."},{"v":3,"t":"Ondje postavi Kovčeg svjedočanstva, onda Kovčeg zakloni zavjesom."},{"v":4,"t":"Potom unesi stol i što na nj spada poredaj; unesi i svijećnjak i svijeće mu pripremi."},{"v":5,"t":"A zlatni žrtvenik za kađenje postavi pred Kovčeg svjedočanstva. Onda objesi zastor nad ulazom u Prebivalište."},{"v":6,"t":"Stavi žrtvenik za žrtve paljenice pred ulaz Prebivališta, Šatora sastanka."},{"v":7,"t":"Između Šatora sastanka i žrtvenika smjesti umivaonik i u nj nalij vode."},{"v":8,"t":"Naokolo napravi dvorište i objesi zastor nad dvorišnim ulazom."},{"v":9,"t":"Zatim uzmi ulja za pomazanje pa pomaži Prebivalište i sve što je u njemu; posveti ga i sav njegov pribor, pa će svetim postati."},{"v":10,"t":"Pomaži potom žrtvenik za žrtve paljenice i sav njegov pribor; posveti žrtvenik i presvetim će žrtvenik postati."},{"v":11,"t":"Pomaži umivaonik s njegovim stalkom: posveti ga!"},{"v":12,"t":"Dovedi zatim Arona i njegove sinove na ulaz Šatora sastanka pa ih operi vodom."},{"v":13,"t":"Stavi onda na Arona posvećenu odjeću; pomaži ga i posveti da mi služi kao svećenik."},{"v":14,"t":"Dovedi i njegove sinove, na njih stavi košulje"},{"v":15,"t":"i pomaži ih, kako si pomazao i njihova oca, da mi služe kao svećenici. Njihovo pomazanje neka ih uvede u vječno svećenstvo u sve njihove naraštaje.”"},{"v":16,"t":"Tako Mojsije učini. Kako mu je Jahve naredio, sve je tako i učinio."},{"v":17,"t":"Prvoga dana prvoga mjeseca druge godine Prebivalište bi podignuto."},{"v":18,"t":"Ovako Mojsije namjesti Prebivalište: razmjesti njegova podnožja, onda uspravi njegove trenice, zatim postavi priječnice i podiže stupove."},{"v":19,"t":"Zatim raspne Šator nad Prebivalište, a povrh njega stavi pokrov Šatora, kako je Jahve Mojsiju naredio."},{"v":20,"t":"Uze onda Svjedočanstvo i stavi ga u Kovčeg; na Kovčeg postavi motke; onda stavi Pomirilište ozgo na Kovčeg."},{"v":21,"t":"Potom unese Kovčeg u Prebivalište; objesi zavjesu za zaklon. Tako zastre Kovčeg svjedočanstva, kako je Jahve i naredio Mojsiju."},{"v":22,"t":"Zatim postavi stol u Šator sastanka, Prebivalištu sa sjeverne strane, ali izvan zavjese."},{"v":23,"t":"Po njemu poreda kruhove pred Jahvom, kako je Jahve naredio Mojsiju."},{"v":24,"t":"Onda smjesti svijećnjak u Šator sastanka naprama stolu, na južnoj strani Prebivališta."},{"v":25,"t":"I postavi svjetiljke pred Jahvom, kako je Jahve naredio Mojsiju."},{"v":26,"t":"Zlatni žrtvenik smjesti u Šator sastanka, pred zavjesu."},{"v":27,"t":"Na njemu zapali miomirisnog tamjana, kako je Jahve naredio Mojsiju."},{"v":28,"t":"Poslije toga stavi zavjesu na ulaz u Prebivalište."},{"v":29,"t":"Kod ulaza u Prebivalište, u Šator sastanka, postavi žrtvenik za žrtve paljenice. Na njemu prinese žrtvu paljenicu i žrtvu od žita, kako je Jahve naredio Mojsiju."},{"v":30,"t":"Između Šatora sastanka i žrtvenika smjesti umivaonik pa u nj ulije vode za pranje."},{"v":31,"t":"Iz njega su Mojsije, Aron i njegovi sinovi prali svoje ruke i svoje noge."},{"v":32,"t":"A prali su se kad su ulazili u Šator sastanka i kad su pristupali k žrtveniku, kako je Jahve naredio Mojsiju."},{"v":33,"t":"Napokon Mojsije napravi dvorište oko Prebivališta i žrtvenika i postavi zavjesu na dvorišnim vratima. Tako Mojsije završi taj posao."},{"v":34,"t":"A onda oblak prekri Šator sastanka i slava Jahvina ispuni Prebivalište."},{"v":35,"t":"Mojsije nije mogao ući u Šator sastanka zbog oblaka koji je na njemu stajao i slave Jahvine koja je ispunjala Prebivalište."},{"v":36,"t":"Sve vrijeme njihova putovanja, kad god bi se oblak digao s Prebivališta, Izraelci bi krenuli;"},{"v":37,"t":"ali ako se oblak ne bi digao, ni oni ne bi na put polazili sve do dana dok se ne bi digao."},{"v":38,"t":"Jer sve vrijeme njihova putovanja oblak Jahvin danju stajaše nad Prebivalištem, a noću bi se u oblaku pojavila vatra vidljiva svemu domu Izraelovu."}]}},"LEV":{"1":{"hr":[{"v":1,"t":"Zovnu Jahve Mojsija te mu iz Šatora sastanka reče:"},{"v":2,"t":"“Govori Izraelcima i kaži im: 'Kad tko od vas želi prinijeti Jahvi žrtvu od stoke, prinijet će je ili od krupne ili od sitne stoke."},{"v":3,"t":"Ako njegov prinos za žrtvu paljenicu bude od krupne stoke, neka prinese muško bez mane. Neka ga dovede k ulazu u Šator sastanka da pred Jahvom bude primljen."},{"v":4,"t":"Neka stavi svoju ruku na glavu žrtve paljenice da mu za njegovo ispaštanje bude primljena."},{"v":5,"t":"Neka zatim zakolje junca pred Jahvom. A Aronovi sinovi, svećenici, neka prinesu krv. Neka njome zapljusnu sve strane žrtvenika koji stoji pred ulazom u Šator sastanka."},{"v":6,"t":"Potom neka se žrtva sadre i rasiječe na dijelove."},{"v":7,"t":"Neka sinovi Aronovi, svećenici, nalože vatru na žrtveniku i na vatru metnu drva."},{"v":8,"t":"Neka zatim sinovi Aronovi, svećenici, naslažu dijelove, s glavom i lojem, na drva što su na vatri na žrtveniku."},{"v":9,"t":"Drobina i noge neka se operu u vodi. A onda neka svećenik sve sažeže u kad na žrtveniku. To je žrtva paljenica, žrtva paljena Jahvi na ugodan miris.'"},{"v":10,"t":"Ako bi htio prinijeti za žrtvu paljenicu od sitne stoke - od ovaca ili koza - neka prinese muško bez mane."},{"v":11,"t":"Neka ga zakolje pred Jahvom, na žrtveniku sa sjeverne strane. Neka zatim Aronovi sinovi, svećenici, zapljusnu žrtvenik krvlju sa svih strana."},{"v":12,"t":"Potom neka je rasijeku na dijelove, a svećenik neka ih, s glavom i lojem, naslaže na drva što su na vatri na žrtveniku."},{"v":13,"t":"Drobina i noge neka se operu u vodi. Onda svećenik neka sve prinese i na žrtveniku sažeže. To je žrtva paljenica, žrtva paljena Jahvi na ugodan miris."},{"v":14,"t":"Ako bi hto prinijeti Jahvi ptice kao žrtvu paljenicu, neka onda prinese grlicu ili golubića."},{"v":15,"t":"Neka ga svećenik prinese k žrtveniku i, zavrnuvši mu vratom, otkine glavu i na žrtveniku sažeže. Zatim neka mu krv iscijedi žrtveniku sa strane."},{"v":16,"t":"Neka mu gušu i perje ukloni i pobaca ih na istočnu stranu žrtvenika, na mjesto za otpatke."},{"v":17,"t":"Neka ga raspori duž obaju krila, ali neka ih ne rastavlja. Onda neka ga svećenik na žrtveniku sažeže na drvima što su na vatri. To je žrtva paljenica, žrtva paljena Jahvi na ugodan miris.”"}]},"2":{"hr":[{"v":1,"t":"“Kad tko želi prinijeti Jahvi žrtvu prinosnicu, neka njegov dar bude od najboljeg brašna; neka ga polije uljem i na nj stavi tamjana."},{"v":2,"t":"Neka ga onda donese Aronovim sinovima, svećenicima. Zatim neka zagrabi šaku od toga brašna i ulja i sav tamjan, pa neka svećenik na žrtveniku to sažeže u kad za spomen-žrtvu. To je žrtva paljena Jahvi na ugodan miris."},{"v":3,"t":"A što od žrtve prinosnice ostane, neka pripadne Aronu i njegovim sinovima - najsvetije od žrtava Jahvi paljenih."},{"v":4,"t":"Ako za žrtvu prinosnicu želiš prinijeti tijesta pečena u peći, neka to budu beskvasne pogače od najboljeg brašna, zamiješene u ulju, ili beskvasne prevrte uljem namazane."},{"v":5,"t":"Ako tvoj dar bude žrtva prinosnica pečena na tavi, neka bude od najboljeg brašna, neukvasana i u ulju zamiješena."},{"v":6,"t":"U komade je izlomi i po njima ulja polij: žrtva je to prinosnica."},{"v":7,"t":"Bude li tvoja prinosnica kuhana u kotluši, neka bude od najboljeg brašna, pripravljena s uljem."},{"v":8,"t":"Donosi Jahvi žrtvu prinosnicu tako pripravljenu! Neka se preda svećeniku, a on će je polagati na žrtvenik."},{"v":9,"t":"Neka svećenik odvoji od žrtve prinosnice dio kao spomen-žrtvu, pa neka ga sažeže u kad na žrtveniku - kao žrtvu paljenu Jahvi na ugodan miris!"},{"v":10,"t":"A što od žrtve prinosnice ostane, neka pripadne Aronu i njegovim sinovima - najsvetije od žrtava Jahvi paljenih."},{"v":11,"t":"Nikakva žrtva prinosnica koju budeš prinosio Jahvi neka ne bude priređivana s kvasom, jer ne smiješ u kad sažigati ni kvasa ni meda kao žrtvu paljenicu."},{"v":12,"t":"Prinosite ih Jahvi kao prvine plodova, ali neka se sa žrtvenika ne viju na ugodan miris."},{"v":13,"t":"Svaku svoju žrtvu prinosnicu posoli. Ne ostavljaj svoje žrtve prinosnice bez soli Saveza sa svojim Bogom: sa svakim svojim prinosom prinesi i sol."},{"v":14,"t":"Ako prinosiš Jahvi žrtvu prinosnicu od prvina, prinesi tu žrtvu od prvina svojih plodova u obliku klasa pržena na vatri ili brašna od samljevenog zrnja."},{"v":15,"t":"Dodaj još ulja i na nju stavi tamjana. To je žrtva prinosnica."},{"v":16,"t":"Onda neka svećenik sažeže u kad za spomen-žrtvu dio kruha i ulja i sav tamjan kao žrtvu Jahvi paljenu.”"}]},"3":{"hr":[{"v":1,"t":"“Ako tko prinosi žrtvu pričesnicu te ako prinosi goveče - žensko ili muško - neka je bez mane što prinosi pred Jahvom."},{"v":2,"t":"Neka stavi svoju ruku na glavu svoje žrtve i zakolje je na ulazu u Šator sastanka. Neka zatim Aronovi sinovi, svećenici, zapljusnu krvlju sve strane žrtvenika."},{"v":3,"t":"Od žrtve pričesne, kao žrtvu paljenu, neka prinese loj što omotava drobinu, sav loj što je oko drobine;"},{"v":4,"t":"oba bubrega i loj što je na njima i na slabinama; pa privjesak s jetre: neka i njega s bubrezima izvadi."},{"v":5,"t":"Zatim neka Aronovi sinovi te dijelove sažegu na žrtveniku sa žrtvom paljenicom koja bude na drvima na vatri. To neka je žrtva paljena Jahvi na ugodan miris."},{"v":6,"t":"Ako tko prinosi za žrtvu pričesnicu od sitne stoke Jahvi, neka prinese bez mane, bilo muško ili žensko."},{"v":7,"t":"Ako na dar prinosi ovcu, neka je prinese pred Jahvom."},{"v":8,"t":"Neka stavi svoju ruku na glavu svoje žrtve i neka je zakolje pred Šatorom sastanka. Zatim neka Aronovi sinovi zapljusnu njezinom krvlju sve strane žrtvenika."},{"v":9,"t":"Od žrtve pričesnice neka prinesu žrtvu paljenu Jahvi: njezin loj, cio pretili rep, otkinuvši ga tik uz hrptenjaču; loj što omotava drobinu, sav loj što je oko drobine;"},{"v":10,"t":"oba bubrega i loj što je na njima i na slabinama; pa privjesak s jetre: neka i njega s bubrezima izvadi."},{"v":11,"t":"Onda neka svećenik to sažeže na žrtveniku u kad - kao hranu vatre u čast Jahvi."},{"v":12,"t":"Ako li prinosi kozu, neka je prinese pred Jahvom:"},{"v":13,"t":"neka stavi svoju ruku na glavu svoje žrtve i neka je zakolje pred Šatorom sastanka. Neka zatim Aronovi sinovi zapljusnu njezinom krvlju sve strane žrtvenika."},{"v":14,"t":"Onda neka od nje prinese, kao paljenu žrtvu Jahvi, loj što omotava drobinu, sav loj što je oko drobine;"},{"v":15,"t":"oba bubrega i loj što je na njima i na slabinama; pa privjesak s jetre; neka i njega s bubrezima izvadi."},{"v":16,"t":"Onda neka ih svećenik sažeže na žrtveniku - žrtvu paljenu Jahvi na ugodan miris. Sav loj pripada Jahvi."},{"v":17,"t":"Neka ovo bude zakon za sva vremena svim vašim naraštajima u kojem god mjestu budete boravili: nipošto ne smijete jesti ni loja ni krvi.”"}]},"4":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Ovako kaži Izraelcima: 'Ako se tko nehotice ogriješi o bilo koju Jahvinu zapovijed te učini što je zabranjeno činiti:"},{"v":3,"t":"Bude li to pomazanjem posvećeni svećenik koji pogriješi i navuče tako krivnju na narod, onda za grijeh koji učini neka prinese Jahvi jedno grlo krupne stoke, jednoga junca bez mane, kao žrtvu okajnicu."},{"v":4,"t":"Neka junca dovede pred Jahvu do ulaza u Šator sastanka; neka juncu na glavu položi svoju ruku i onda junca zakolje pred Jahvom."},{"v":5,"t":"Zatim neka pomazanjem posvećeni svećenik uzme krvi od junca i donese je u Šator sastanka."},{"v":6,"t":"Onda neka svećenik zamoči svoj prst u krv i tom krvlju neka sedam puta poškropi prednju stranu zavjese Svetišta, pred Jahvom."},{"v":7,"t":"Potom neka svećenik stavi te krvi na rogove žrtvenika za miomirisni kad koji se dimi pred Jahvom u Šatoru sastanka. Svu ostalu krv od junca neka izlije podno žrtvenika za žrtve paljenice što se nalazi na ulazu u Šator sastanka."},{"v":8,"t":"Iz junca što ga prinosi kao žrtvu okajnicu neka izvadi: loj što omotava drobinu, sav loj što je oko drobine;"},{"v":9,"t":"oba bubrega i loj što je na njima i na slabinama, privjesak s jetre; neka i njega izvadi s bubrezima;"},{"v":10,"t":"onako kako se uzima dio iz vola žrtve pričesnice. Neka ih zatim svećenik sažeže u kad na žrtveniku za žrtve paljenice."},{"v":11,"t":"Kožu od junca, sve meso od njega, njegovu glavu, njegove noge, drobinu i njegovu nečist"},{"v":12,"t":"- svega junca - neka iznese na čisto mjesto izvan tabora gdje se pepeo izasiplje i neka ga spali na vatri od drva; tu na pepelu neka se junac spali.'”"},{"v":13,"t":"“Ako sva izraelska zajednica nehotično pogriješi počinivši štogod što je Jahve zabranio pa tako postanu krivi a ne budu svjesni krivnje,"},{"v":14,"t":"onda, kad se sazna za učinjeni prijestup, neka zajednica prinese jedno grlo krupne stoke - jednoga junca bez mane - kao žrtvu okajnicu. Neka ga dovedu pred Šator sastanka."},{"v":15,"t":"Tu pred Jahvom neka starješine zajednice polože svoje ruke juncu na glavu. Neka se onda junac zakolje pred Jahvom."},{"v":16,"t":"Neka zatim pomazanjem posvećeni svećenik donese krvi od junca u Šator sastanka;"},{"v":17,"t":"neka svećenik zamoči svoj prst u krv i sedam puta poškropi prednju stranu zavjese, pred Jahvom."},{"v":18,"t":"Neka zatim stavi krvi na rogove žrtvenika koji se nalazi pred Jahvom u Šatoru sastanka. Svu ostalu krv neka izlije podno žrtvenika za žrtve paljenice što se nalazi na ulazu u Šator sastanka."},{"v":19,"t":"S junca neka skine sav loj i sažeže ga u kad na žrtveniku."},{"v":20,"t":"I s juncem neka uradi kako je uradio s onim juncem žrtve okajnice - tako neka učini i s tim. I pošto svećenik nad članovima zajednice izvrši obred pomirenja, bit će im oprošteno."},{"v":21,"t":"Neka odnese junca izvan tabora i spali ga kako je spalio i prvoga junca. To je žtrva za prijestup zajednice.”"},{"v":22,"t":"“Ako nehotično pogriješi glavar i učini štogod što je Jahve, Bog njegov, zabranio i tako sagriješi,"},{"v":23,"t":"onda, kad ga obznane o prijestupu koji je počinio, neka kao svoj prinos donese muško jare bez mane."},{"v":24,"t":"Položivši svoju ruku jaretu na glavu, neka ga zakolje na mjestu gdje se kolju pred Jahvom žrtve paljenice. To je žrtva okajnica."},{"v":25,"t":"Svećenik neka uzme na svome prstu krvi od žrtve okajnice pa je stavi na rogove žrtvenika za žrtve paljenice. A svu ostalu krv neka izlije podno žrtvenika za žrtve paljenice."},{"v":26,"t":"Sav loj neka sažeže u kad na žrtveniku kao i loj sa žrtve pričesnice. Neka tako svećenik nad glavarom izvrši obred pomirenja za njegov grijeh, pa će mu biti oprošteno.”"},{"v":27,"t":"“Ako tko od običnoga puka nehotično pogriješi učinivši štogod što je Jahve zabranio i tako sagriješi,"},{"v":28,"t":"onda, kad ga obznane o prijestupu koji je počinio, neka kao svoj prinos za grijeh koji je počinio donese žensko jare bez mane."},{"v":29,"t":"Neka stavi svoju ruku na glavu okajnice i zakolje žrtvu okajnicu na mjestu za žrtve paljenice."},{"v":30,"t":"Neka svećenik uzme krvi na svome prstu pa je stavi na rogove žrtvenika za žrtve paljenice. A svu ostalu krv neka izlije podno žrtvenika."},{"v":31,"t":"Neka zatim izvadi sav njezin loj kao što se vadi loj iz žrtve pričesnice; neka ga onda svećenik sažeže u kad na žrtveniku kao ugodan miris Jahvi. Kad svećenik izvrši nad tim čovjekom obred pomirenja, bit će mu oprošteno."},{"v":32,"t":"Ako bi tko htio dovesti janje kao žrtvu okajnicu, neka dovede žensko bez mane."},{"v":33,"t":"Položivši svoju ruku na glavu žrtve okajnice, neka je zakolje kao žrtvu okajnicu na mjestu gdje se kolju žrtve paljenice."},{"v":34,"t":"Neka onda svećenik uzme krvi od žrtve okajnice na svome prstu pa je stavi na rogove žrtvenika za žrtve paljenice. A svu ostalu krv neka izlije podno žrtvenika."},{"v":35,"t":"Neka zatim izvadi sav njezin loj kao što se vadi loj iz žrtve pričesnice. Neka to svećenik sažeže u kad povrh žrtava paljenih Jahvi u čast. Neka tako svećenik izvrši nad tim čovjekom obred pomirenja za grijeh koji je počinio, pa će mu biti oprošteno.”"}]},"5":{"hr":[{"v":1,"t":"“Zgriješi li tko tako što čuje riječi proklinjanja a odbije da svjedoči iako je mogao biti svjedokom jer je ili sam vidio ili doznao pa tako nosi krivnju na sebi;"},{"v":2,"t":"ili ako tko dirne kakav nečist predmet, strv nečiste zvijeri, strv nečista živinčeta ili strv nečista puzavca - i u neznanju postane nečist i odgovoran;"},{"v":3,"t":"ili kad se tko dotakne nečistoće čovječje, bilo to što mu drago od čega se nečistim postaje i toga ne bude svjestan, kad dozna, biva odgovoran;"},{"v":4,"t":"nadalje, kad tko nepromišljeno izusti zakletvu na dobro ili zlo - na što se već čovjek nepromišljeno zaklinje - i toga ne bude svjestan, onda, kad dozna, biva odgovoran;"},{"v":5,"t":"ako, dakle, tko postane odgovoran u bilo čemu od toga, neka prizna počinjeni grijeh."},{"v":6,"t":"I neka prinese Jahvi kao žrtvu naknadnicu za počinjeni grijeh jednu ženku od sitne stoke, janje ili kozle, kao žrtvu okajnicu. Neka svećenik izvrši nad njim obred pomirenja koji će ga osloboditi od njegova grijeha.”"},{"v":7,"t":"“Ako mu sredstva ne dopuštaju da pribavi glavu sitne stoke, neka Jahvi, kao naknadnicu za počinjeni grijeh, prinese dvije grlice ili dva golubića; jedno kao žrtvu okajnicu, a drugo kao žrtvu paljenicu."},{"v":8,"t":"Neka ih donese svećeniku, a on neka najprije prinese ono što je određeno kao žrtva okajnica. Stisnuvši ga za vrat, neka mu slomi šiju, ali neka glave ne otkida."},{"v":9,"t":"Neka krvlju žrtve poškropi žrtvenik sa strane, a ostatak krvi neka se iscijedi podno žrtvenika. To je žrtva okajnica."},{"v":10,"t":"Onda neka drugo prinese kao žrtvu paljenicu prema propisu. Neka tako svećenik nad tim čovjekom izvrši obred pomirenja za grijeh koji je počinio, i bit će mu oprošteno."},{"v":11,"t":"Ako mu sredstva ne dopuštaju da pribavi dvije grlice ili dva golubića, neka Jahvi, u zadovoljštinu za počinjeni grijeh, prinese jednu desetinu efe njaboljeg brašna. Ulja u nj neka ne ulijeva niti na nj tamjana stavlja jer je žrtva okajnica."},{"v":12,"t":"Kada to donese svećeniku, neka svećenik zagrabi punu pregršt kao spomen-žrtvu i na žrtveniku sažeže u čast Jahvi povrh paljenih žrtava. To je žrtva okajnica."},{"v":13,"t":"Neka tako svećenik izvrši nad tim čovjekom obred pomirenja za grijeh koji je počinio u bilo kojem od tih slučajeva, pa će mu biti oprošteno. Ono ostalo neka pripadne svećeniku kao i od žrtve prinosnice.”"},{"v":14,"t":"Još reče Jahve Mojsiju:"},{"v":15,"t":"“Ako tko počini pronevjerenje ogriješivši se nehotično o svete stvari Jahvine, neka za naknadu, kao žrtvu naknadnicu, prinese Jahvi, iz svoga stada, ovna bez mane, vrijedna - po tvojoj procjeni - najmanje dva šekela srebra - prema cijeni hramskog šekela."},{"v":16,"t":"Neka nadoknadi koliko se ogriješio o svete stvari i tome doda još petinu i neka dadne svećeniku. Neka svećenik nad njim izvrši obred pomirenja ovnom žrtve naknadnice, i bit će mu oprošteno."},{"v":17,"t":"Ako tko i ne znajući pogriješi i učini štogod što je Jahve zabranio, kriv je, pa neka snosi posljedice svoje krivnje."},{"v":18,"t":"Neka svećeniku dovede za naknadnicu iz svoga stada ovna bez mane, prema tvojoj procjeni. Neka svećenik nad tim čovjekom izvrši obred pomirenja za pogrešku što je počinio u neznanju, i bit će mu oprošteno."},{"v":19,"t":"To je žrtva naknadnica; on je doista bio odgovoran Jahvi.”"},{"v":20,"t":"Jahve još reče Mojsiju:"},{"v":21,"t":"“Kad se tko ogriješi i počini pronevjeru prema Jahvi prevarivši svoga bližnjega u pologu ili pohrani, a tako i krađom ili iskorištavanjem svoga bližnjega;"},{"v":22,"t":"ili, nađe li što je bilo izgubljeno pa slaže i krivo se zakune u bilo kojem grijehu što ga čovjek može učiniti;"},{"v":23,"t":"ako tko tako pogriješi i kriv postane, onda ono što je krađom oduzeo ili što je iskorištavanjem namakao; ili polog što mu je bio povjeren; ili izgubljenu stvar što ju je našao;"},{"v":24,"t":"ili ono za što se bio krivo zakleo - neka u cijelosti vrati i, dodavši tome petinu, neka dadne onome kome pripada istoga dana kad spozna svoju krivnju."},{"v":25,"t":"Neka potom svećeniku za naknadu, kao žrtvu naknadnicu Jahvi, dovede iz svog stada jednoga ovna bez mane, prema tvojoj procjeni,"},{"v":26,"t":"a svećenik neka nad tim čovjekom izvrši obred pomirenja pred Jahvom, i bit će mu oprošteno, ma kakvo bilo nedjelo kojega je krivac.”"}]},"6":{"hr":[{"v":1,"t":"Jahve još reče Mojsiju:"},{"v":2,"t":"“Naredi Aronu i njegovim sinovima: 'Ovakav je obred za žrtvu paljenicu: žrtva paljenica neka ostane na žeravi na žrtveniku svu noć do jutra; i vatra neka neprestano gori na žrtveniku."},{"v":3,"t":"Neka svećenik stavi na se lanenu košulju, na svoje tijelo neka navuče lanene gaće; zatim neka zgrne zamašćeni pepeo u što je vatra pretvorila žrtvu paljenicu na žrtveniku i neka ga stavi pokraj žrtvenika."},{"v":4,"t":"Potom neka svuče svoje ruho i na se obuče drugo te neka odnese zamašćeni pepeo na čisto mjesto izvan tabora."},{"v":5,"t":"Vatra na žrtveniku mora uvijek gorjeti; ne smije se gasiti. Neka svako jutro svećenik na nju naloži drva i onda na nju naslaže žrtvu paljenicu. Tu neka u kad sažiže loj sa žrtava pričesnica."},{"v":6,"t":"Neka na žrtveniku trajno gori vatra; neka se ne gasi.'”"},{"v":7,"t":"“Ovo je obred za žrtvu prinosnicu: neka je Aronovi sinovi pronose u nazočnosti Jahve pred žrtvenikom."},{"v":8,"t":"Pošto jedan od njih zagrabi pregršt najboljeg brašna i ulja sa žrtve prinosnice i sav tamjan što bude na njoj, pošto to sažeže na žrtveniku kao spomen-žrtvu, ugodan miris Jahvi,"},{"v":9,"t":"neka ostatak u obliku beskvasnih kruhova pojedu Aron i njegovi sinovi; neka ga jedu na posvećenu mjestu - u dvorištu Šatora sastanka."},{"v":10,"t":"Neka se ne peče s kvascem. To je dio žrtava meni paljenih što im ga ja dajem - dio najsvetiji, jednako kao i žrtva okajnica i kao žrtva naknadnica."},{"v":11,"t":"Svaki muškarac Aronova potomstva može jesti taj dio od žrtava paljenih Jahvi, i to je vječni zakon za sve vaše naraštaje: i tko ih se god dotakne, bit će posvećen.”"},{"v":12,"t":"Jahve još reče Mojsiju:"},{"v":13,"t":"“Neka Aron i njegovi sinovi na dan svoga pomazanja prinesu Jahvi ovaj prinos: desetinu efe najboljeg brašna kao redovitu žrtvu prinosnicu, polovinu ujutro, a polovinu uvečer."},{"v":14,"t":"Neka bude pripravljena u tavi na ulju. Donesi je dobro namočenu i prinesi Jahvi kao ugodan miris, kao žrtvu prinosnicu od više komada."},{"v":15,"t":"Neka je tako pripravi svećenik koji od njegovih sinova bude pomazan da ga naslijedi. To je vječni zakon. Neka se ta žrtva Jahvi sva sažeže!"},{"v":16,"t":"Svaka svećenička žrtva prinosnica treba da bude posve spaljena; neka se od nje ne jede.”"},{"v":17,"t":"Još reče Jahve Mojsiju:"},{"v":18,"t":"“Kaži Aronu i njegovim sinovima: 'Ovo je obred žrtvovanja za grijeh: žrtva okajnica neka se zakolje pred Jahvom na mjestu gdje se kolje žrtva paljenica - presveta je!"},{"v":19,"t":"Svećenik koji prinosi tu žrtvu okajnicu neka od nje i jede; neka se ona jede na posvećenu mjestu, u dvorištu Šatora sastanka."},{"v":20,"t":"Tko se god dotakne njezina mesa bit će posvećen; ako krv poštrapa odijelo, poštrapani dio neka se ispere na posvećenu mjestu."},{"v":21,"t":"A posuda od ilovače u kojoj bude meso kuhano neka se razbije; a ako bude kuhano u posudi od tuča, neka se istare i vodom ispere."},{"v":22,"t":"Svaki muški od svećeničke loze može od nje jesti - presveta je!"},{"v":23,"t":"Ali nijedna žrtva okajnica od koje je krv donesena u Šator sastanka za obred pomirenja u Svetištu neka se ne jede, nego na vatri spali.'”"}]},"7":{"hr":[{"v":1,"t":"“Ovo je obred za žrtvu naknadnicu."},{"v":2,"t":"Nadasve je sveta! Neka se žrtva naknadnica zakolje na mjestu gdje se kolju žrtve paljenice, a njezinom krvlju neka svećenik zapljusne sve strane žtrvenika."},{"v":3,"t":"Zatim neka prinese sav loj s nje: pretili rep, loj što omotava drobinu,"},{"v":4,"t":"oba bubrega i loj što je na njima i na slabinama; pa privjesak s jetre: neka i njega izvadi s bubrezima!"},{"v":5,"t":"Neka ih svećenik sažeže na žrtveniku kao žrtvu u čast Jahvi paljenu. To je žrtva naknadnica."},{"v":6,"t":"Svaki muški od svećeničke loze može od nje jesti. Neka je jedu na posvećenu mjestu - presveta je!"},{"v":7,"t":"Kakva je žrtva okajnica, takva je i žrtva naknadnica; jedno je pravilo za njih: neka pripadne svećeniku koji njome vrši obred pomirenja."},{"v":8,"t":"Tako isto koža od žrtve koju tko preda svećeniku da bude prinesena za žrtvu paljenicu neka pripadne svećeniku."},{"v":9,"t":"Nadalje, svaka žrtva prinosnica što bude pečena u peći, kao i svaka što bude zgotovljena u kotluši ili na tavi, neka pripadne svećeniku koji je prinosi."},{"v":10,"t":"A svaka žrtva prinosnica, zamiješena s uljem ili nasuho, neka pripadne svim Aronovim sinovima bez razlike!”"},{"v":11,"t":"“Ovo je obred za žrtvu pričesnicu koja će se prinositi Jahvi."},{"v":12,"t":"Ako se prinosi u zahvalu, neka se zajedno sa žrtvom zahvalnicom prinesu i beskvasne pogače uljem zamiješene; beskvasne prevrte uljem namazane i kolači od najboljeg brašna, zamiješeni uljem."},{"v":13,"t":"Ovaj prinos, nadopunjen kolačima od ukvasanoga tijesta, neka se prinosi zajedno sa žrtvom pričesnicom u zahvalu."},{"v":14,"t":"Od svake ovakve žrtve neka se prinese po jedan kolač na dar Jahvi. To neka bude za svećenika koji zapljuskuje krv od žrtve pričesnice."},{"v":15,"t":"A meso žrtve pričesnice neka se pojede istoga dana kad bude žrtvovana; neka se od nje ne ostavlja ništa za sutradan."},{"v":16,"t":"A bude li prinos žrtva zavjetnica ili žrtva dragovoljna, neka se jede na dan kad se žrtva prinosi. Što ostane od nje neka se jede sutradan."},{"v":17,"t":"A što još mesa od žrtve preteče, neka se treći dan na vatri spali.”"},{"v":18,"t":"“Ako bi tko jeo meso žrtve pričesnice i treći dan, žrtva neće biti primljena niti će onome koji je prinosi biti uračunata. To je meso kvarno, i onaj koji od toga jede neka i posljedice krivnje snosi!"},{"v":19,"t":"Meso koje se dotakne bilo čega nečista neka se ne jede nego na vatri spali! Inače, tko je god čist može jesti meso."},{"v":20,"t":"A tko bi nečist jeo mesa od žrtve pričesnice što je bila Jahvi prinesena takav neka se iskorijeni iz svoga naroda."},{"v":21,"t":"Kad se tko dotakne bilo čega nečista - bila to nečist čovječja, kakva nečista životinja ili bilo kakvo nečisto stvorenje - pa pojede mesa od žrtve pričesnice koja je prinesena Jahvi takav neka se iskorijeni iz svoga naroda!”"},{"v":22,"t":"Reče Jahve Mojsiju:"},{"v":23,"t":"“Ovako kaži Izraelcima: 'Ne jedite loja ni volujskoga, ni ovčjega, ni kozjega."},{"v":24,"t":"Loj sa životinje koja ugine, ili koju divlje zvijeri razderu, može se upotrijebiti za bilo što, ali ga ne smijete jesti."},{"v":25,"t":"Tko god jede loj od životinje koja se može prinijeti Jahvi kao žrtva paljenica takav neka se iskorijeni iz svoga naroda."},{"v":26,"t":"Ne smijete uživati krvi ni od ptica ni od stoke ni u kojem svome prebivalištu."},{"v":27,"t":"Tko bi god uživao bilo kakvu krv neka se iskorijeni iz svoga naroda.'”"},{"v":28,"t":"Jahve još reče Mojsiju:"},{"v":29,"t":"“Ovako kaži Izraelcima: 'Prinos Jahvi od žrtve pričesnice mora donijeti onaj koji Jahvi prinosi žrtvu pričesnicu."},{"v":30,"t":"Svojim vlastitim rukama neka prinese Jahvi žrtvu paljenicu; neka prinese loj i grudi; grudi neka se prinesu pred Jahvom kao žrtva prikaznica."},{"v":31,"t":"Neka svećenik sažeže loj na žrtveniku, a grudi neka pripadnu Aronu i njegovim sinovima."},{"v":32,"t":"Desno pleće od svojih žrtava pričesnica dajte svećeniku na dar."},{"v":33,"t":"Onome Aronovu sinu koji bude prinosio krv i loj sa žrtve pričesnice neka u dio pripadne desno pleće."},{"v":34,"t":"Jer ja uzimam od Izraelaca grudi od žrtava pričesnica što se prinose kao žrtva prikaznica i pleće žrtve podizanice te ih predajem svećeniku Aronu i njegovim sinovima. To je trajna odredba za Izraelce."},{"v":35,"t":"To je dohodak Aronov i njegovih sinova od žrtava paljenih u čast Jahvi; dodjeljuje im se od onog dana kad se dovedu da vrše svećeničku službu u čast Jahvi."},{"v":36,"t":"Jahve je naredio da im se od dana kad budu pomazani to daje kao pristojbina od Izraelaca. To je trajna odredba za njihove naraštaje'.”"},{"v":37,"t":"To je obred za žrtvu paljenicu, prinosnicu, okajnicu, naknadnicu, žrtvu posvetnicu i žrtvu pričesnicu"},{"v":38,"t":"koji je Jahve naredio Mojsiju na Sinajskom brdu kad je zapovjedio Izraelcima da Jahvi u Sinajskoj pustinji prinose žrtve."}]},"8":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Uzmi Arona, a s njim i njegove sinove; ruho, ulje pomazanja, junca žrtve okajnice, dva ovna i košaru beskvasnih kruhova"},{"v":3,"t":"te skupi svu zajednicu na ulazu u Šator sastanka.”"},{"v":4,"t":"Mojsije učini kako mu je Jahve naredio, i zajednica se sabra na ulazu u Šator sastanka."},{"v":5,"t":"Tada Mojsije progovori zajednici: “Ovo je Jahve zpovjedio da se učini.”"},{"v":6,"t":"Izvede zatim Mojsije Arona i njegove sinove pa ih u vodi opra."},{"v":7,"t":"Obuče na nj haljinu, opasa ga pojasom, ogrnu ga ogrtačem i stavi mu oplećak. Zatim ga opasa tkanicom oplećka i njome pritegnu uza nj oplećak."},{"v":8,"t":"Stavi mu naprsnik, a u naprsnik metnu Urim i Tumim."},{"v":9,"t":"Na glavu mu stavi mitru, a sprijeda na mitru postavi zlatnu pločicu - sveti vijenac - kako je Jahve naredio Mojsiju."},{"v":10,"t":"Uzme zatim Mojsije ulje pomazanja te pomaže Prebivalište i sve što je u njemu da ih posveti."},{"v":11,"t":"Sedam puta poškropi njime žrtvenik te pomaže žrtvenik i sav njegov pribor, umivaonik s njegovim stalkom da ih posveti."},{"v":12,"t":"Izlije ulja pomazanja Aronu na glavu te ga pomaže da ga posveti."},{"v":13,"t":"Potom Mojsije dovede Aronove sinove; na njih obuče haljine, pasovima ih opaše i poveze im zavije, kako je Jahve Mojsiju naredio."},{"v":14,"t":"Dovede potom junce žrtve okajnice. Aron i njegovi sinovi stave svoje ruke na glavu juncu žrtve okajnice."},{"v":15,"t":"Zatim ga Mojsije zakolje. Onda uzme krvi pa je svojim prstom stavi na rogove oko žrtvenika. Tako žrtvenik očisti. Zatim izlije krv podno žrtvenika; posveti ga, izvršivši na njemu obred pomirenja."},{"v":16,"t":"Zatim Mojsije uzme sav loj što je bio oko drobine, privjesak s jetre, oba bubrega i njihov loj, pa to sažeže u kad na žrtveniku."},{"v":17,"t":"A kožu od junca, njegovo meso i njegovu nečist spali u vatri izvan tabora, kako je Jahve naredio Mojsiju."},{"v":18,"t":"Dovede potom ovna za žrtvu paljenicu. Aron i njegovi sinovi stave svoje ruke ovnu na glavu."},{"v":19,"t":"Sad ga Mojsije zakolje. Onda krvlju zapljusne žrtvenik sa svih strana."},{"v":20,"t":"Pošto isiječe ovna na dijelove, Mojsije sažeže u kad glavu, dijelove i loj."},{"v":21,"t":"U vodi opere drobinu i noge pa u kad sažeže na žrtveniku svega ovna. Bila je to žrtva paljenica na ugodan miris - žrtva u čast Jahvi paljena - kako je Jahve naredio Mojsiju."},{"v":22,"t":"Zatim dovede drugoga ovna, ovna za žrtvu posvetnicu. Aron i njegovi sinovi stave svoje ruke ovnu na glavu."},{"v":23,"t":"Mojsije ga zakolje. Onda uzme krvi pa stavi na resu Aronova desnog uha, na palac njegove desne ruke i na palac njegove desne noge."},{"v":24,"t":"Potom Mojsije dovede Aronove sinove, pa im stavi iste krvi na resu desnog uha, na palac desne ruke i na palac desne noge. Zatim Mojsije krvlju zapljusne žrtvenik sa svih strana."},{"v":25,"t":"Poslije toga uzme loj, pretili rep, loj što je bio oko drobine, privjesak s jetre, oba bubrega i njihov loj - i desno pleće;"},{"v":26,"t":"a iz košare beskvasnih kruhova, što je stajala pred Jahvom, uzme jednu beskvasnu pogaču, jednu prevrtu s uljem i jedan kolač i postavi ih na loj i desno pleće."},{"v":27,"t":"Sve to položi na ruke Arona i na ruke njegovih sinova pa to prinese kao žrtvu prikaznicu pred Jahvom."},{"v":28,"t":"Potom Mojsije opet to uzme s njihovih ruku i sažeže u kad na žrtveniku povrh žrtve paljenice. Bila je to žrtva posvetnica na ugodan miris, žrtva u čast Jahvi paljena."},{"v":29,"t":"Naposljetku Mojsije uzme grudi i prinese ih kao žrtvu prikaznicu pred Jahvom. To je bila pristojbina Mojsiju od ovna žrtve posvetnice, kako je Jahve Mojsiju naredio."},{"v":30,"t":"Zatim Mojsije uze ulja za pomazanje i krvi što je bila na žrtveniku te poškropi Arona i njegove haljine, a tako i njegove sinove i njihove haljine. Tako posveti Arona i njegove haljine; njegove sinove i njihove haljine."},{"v":31,"t":"Onda reče Mojsije Aronu i njegovim sinovima: “Skuhajte to meso na ulazu u Šator sastanka i ondje ga blagujte s kruhom što je u košari za žrtvu posvetnicu, kako sam naredio. Neka ga jedu Aron i njegovi sinovi!"},{"v":32,"t":"A što od mesa i kruha ostane, spalite na vatri."},{"v":33,"t":"Sedam dana ne odlazite s ulaza Šatora sastanka - do dana kad se navrši rok vašega svećeničkog posvećenja. Jer sedam dana treba za vaše posvećenje."},{"v":34,"t":"Kako se radilo danas, Jahve je naredio da se tako radi dalje, da se nad vama izvrši obred pomirenja."},{"v":35,"t":"Zato ostanite na ulazu Šatora sastanka sedam dana, danju i noću vršeći što je Jahve naredio, da ne pomrete. Takvu sam ja zapovijed dobio.”"},{"v":36,"t":"Aron i njegovi sinovi učiniše sve što je Jahve naredio preko Mojsija."}]},"9":{"hr":[{"v":1,"t":"Osmoga dana Mojsije pozva Arona, njegove sinove i starješine Izraelove"},{"v":2,"t":"i reče Aronu: “Uzmi jedno tele za žrtvu okajnicu, jednoga ovna za žrtvu paljenicu, oboje bez mane, i dovedi ih pred Jahvu."},{"v":3,"t":"A Izraelcima reci ovako: 'Uzmite jednoga jarca za žrtvu okajnicu, tele i janje od godine, oboje bez mane, za žrtvu paljenicu;"},{"v":4,"t":"a junca i ovna za žrtvu pričesnicu da žrtvujete pred Jahvom; napokon prinosnicu, s uljem zamiješenu; jer će vam se danas Jahve ukazati.'”"},{"v":5,"t":"Dovedu oni pred Šator sastanka što je Mojsije naredio; naprijed stupi sva zajednica i stane pred Jahvu."},{"v":6,"t":"“Ovo je zapovijed”, reče Mojsije, “koju je Jahve izdao. Izvršite je, da vam se pokaže slava Jahvina.”"},{"v":7,"t":"Zatim Mojsije reče Aronu: “Stupi k žrtveniku, prinesi svoju žrtvu okajnicu i svoju žrtvu paljenicu i tako izvrši obred pomirenja za se i svoj dom; onda prinesi dar naroda i za nj izvrši obred pomirenja, kako je Jahve naredio.”"},{"v":8,"t":"Aron se primače žrtveniku i zakla tele žrtve za svoj vlastiti grijeh."},{"v":9,"t":"Zatim mu Aronovi sinovi donesu krvi. On u nju zamoči svoj prst i stavi je na rogove žrtvenika. Potom ostalu krv izli podno žrtvenika."},{"v":10,"t":"A loj, bubrege i privjesak s jetre žrtve okajnice sažeže u kad na žrtveniku, kako je Jahve naredio Mojsiju."},{"v":11,"t":"Meso i kožu spali na vatri izvan tabora."},{"v":12,"t":"Zakolje poslije toga žrtvu paljenicu, od koje mu sinovi Aronovi pruže krv. On njome zapljusne žrtvenik sa svih strana."},{"v":13,"t":"Dodaju mu i žrtvu paljenicu, dio po dio, a tako i glavu, i on je sažeže u kad na žrtveniku."},{"v":14,"t":"Drobinu i noge opere pa i njih na žrtveniku sažeže u kad povrh žrtve paljenice."},{"v":15,"t":"Zatim prinese dar naroda. Uze jarca žrtve okajnice za grijehe naroda, zakla ga i prinese kao žrtvu okajnicu, isto onako kao i prijašnju."},{"v":16,"t":"Donese potom žrtvu paljenicu i prinese je prema propisu."},{"v":17,"t":"Donijevši poslije toga žrtvu prinosnicu, od nje zagrabi pregršt i sažeže na žrtveniku u kad povrh jutarnje žrtve paljenice."},{"v":18,"t":"Napokon zakolje junca i ovna kao žrtvu pričesnicu za narod. Aronovi mu sinovi pruže krv, a on zapljusne žrtvenik sa svih strana;"},{"v":19,"t":"dodaju mu i loj s junca i ovna, pretili rep, loj oko drobine, bubrege i privjesak s jetre."},{"v":20,"t":"Metnuvši te masne dijelove na grudi, sažga ih u kad na žrtveniku."},{"v":21,"t":"A grudi i desno pleće Aron prinese kao žrtvu prikaznicu pred Jahvom, kako je Mojsije naredio."},{"v":22,"t":"Tada Aron podiže ruke spram naroda i blagoslovi ga. Pošto prinese žrtvu okajnicu, paljenicu i pričesnicu, siđe."},{"v":23,"t":"Poslije toga Mojsije i Aron uđoše u Šator sastanka. Kad iziđoše, blagosloviše narod. Slava Jahvina pokaza se svemu narodu."},{"v":24,"t":"Ispred Jahve izbi oganj i sažga žrtvu paljenicu i masne komade na žrtveniku. A sav narod, vidjevši to, viknu od veselja i pade ničice."}]},"10":{"hr":[{"v":1,"t":"A sinovi Aronovi Nadab i Abihu uzmu svaki svoj kadionik; stave u nj vatre i na nju metnu tamjana da prinesu pred Jahvom neposvećenu vatru, koju im on ne bijaše propisao."},{"v":2,"t":"Ali izbije plamen ispred Jahve te ih proguta - poginuše oni pred Jahvom."},{"v":3,"t":"Nato će Mojsije Aronu: “To je ono što je Jahve navijestio: Po onima koji su mi blizu svetim ću se pokazati; pred svim ću se pukom proslaviti.” Aron je šutio."},{"v":4,"t":"Mojsije zovnu Mišaela i Elsafana, sinove Aronova strica Uziela, pa im reče: “Dođite i odnesite svoju braću ispred Svetišta u polje izvan tabora!”"},{"v":5,"t":"Oni dođu i odnesu ih u njihovim košuljama u polje izvan tabora, kako je Mojsije rekao."},{"v":6,"t":"Poslije toga Mojsije reče Aronu i njegovim sinovima, Eleazaru i Itamaru: “Ne raščupavajte svoje kose niti razdirite svojih haljina da ne poginete i da se On ne razljuti na svekoliku zajednicu. Vaša braća i sav dom Izraelov neka oplakuje one koje je vatra Jahvina sažegla."},{"v":7,"t":"Ne smijete odlaziti s ulaza u Šator sastanka da ne pomrete, jer na vama je Jahvino ulje pomazanja.” Oni učine po riječi Mojsijevoj."},{"v":8,"t":"Jahve reče Aronu:"},{"v":9,"t":"“Kad ulazite u Šator sastanka, nemojte piti vina niti opojnoga pića, ni ti ni tvoji sinovi s tobom! Tako nećete poginuti. To je trajan zakon za vaše naraštaje;"},{"v":10,"t":"da možete lučiti posvećeno od običnoga, čisto od nečistoga;"},{"v":11,"t":"da možete učiti Izraelce svim zakonima što ih je Jahve predao preko Mojsija.”"},{"v":12,"t":"Onda Mojsije rekne Aronu i njegovim preživjelim sinovima, Eleazaru i Itamaru: “Uzimajte od žrtve prinosnice što preostaje nakon prinesene žrtve u čast Jahvi paljene i beskvasnu je uza žrtvenik jedite jer je vrlo sveta."},{"v":13,"t":"Blagujte je u svetom mjestu, jer to je - tako je meni naređeno - pristojbina tvoja i pristojbina tvojih sinova od žrtava paljenih u čast Jahvi."},{"v":14,"t":"A grudi žrtve prikaznice i pleće žrtve podizanice ti i tvoji sinovi i tvoje kćeri s tobom jedite na bilo kojem čistom mjestu. Jer to je dodijeljeno za pristojbinu tebi i tvojim sinovima od izraelskih žrtava pričesnica."},{"v":15,"t":"Pleće žrtve podizanice i grudi žrtve prikaznice što se donose zajedno s lojem, na vatri paljenim - pošto budu prineseni za žrtvu prikaznicu pred Jahvom - neka pripadnu tebi i tvojim sinovima s tobom. To je, kako je Jahve naredio, trajan zakon.”"},{"v":16,"t":"Potom se Mojsije potanje raspita o jarcu žrtve okajnice. Već je bio spaljen. On se razljuti na Eleazara i Itamara, Aronove preživjele sinove, pa rekne:"},{"v":17,"t":"“Zašto ste jeli žrtvu okajnicu na svetome mjestu? Vrlo ja sveta! To vam je dao Jahve da uklanjate krivnju sa zajednice vršeći nad njom obred pomirenja pred Jahvom."},{"v":18,"t":"Budući da krv žrtve nije bila unesena unutar Svetišta, morali ste je blagovati u Svetištu, kako mi je bilo zapovjeđeno.”"},{"v":19,"t":"Nato će Aron Mojsiju: “Danas su, eto, prinijeli svoju žrtvu okajnicu i svoju žrtvu paljenicu pred Jahvom! Što bi se meni dogodilo da sam ja danas jeo od žrtve okajnice? Bi li to bilo milo Jahvi?”"},{"v":20,"t":"Kad Mojsije to ču, odobri."}]},"11":{"hr":[{"v":1,"t":"Jahve reče Mojsiju i Aronu:"},{"v":2,"t":"“Ovako kažite Izraelcima: 'Ovo su životinje koje između svih četveronožaca na zemlji možete jesti:"},{"v":3,"t":"svaku koja ima papke, ali papke razdvojene, i koja preživa možete jesti."},{"v":4,"t":"Ali ove, iako preživaju ili papke imaju, ne smijete jesti: devu, jer iako preživa, razdvojena papka nema - za vas je nečista;"},{"v":5,"t":"svisca, jer iako preživa, razdvojena papka nema - za vas je nečist;"},{"v":6,"t":"arnebeta, iako preživa, razdvojena papka nema - za vas je nečist."},{"v":7,"t":"A svinja, iako ima papak, i to papak razdvojen, ne preživa - za vas je nečista."},{"v":8,"t":"Njihova mesa nemojte jesti niti se njihove strvine doticati - za vas su one nečiste.'”"},{"v":9,"t":"Od svih vodenih životinja ove možete jesti: sve što živi u vodi, bilo u morima, bilo u rijekama, a ima peraje i ljuske možete jesti."},{"v":10,"t":"A što u morima i rijekama nema peraja i ljusaka - sve životinjice u vodi, sva živa vodena bića - neka su vam odvratna"},{"v":11,"t":"i odvratna neka vam ostanu! Mesa od njih nemojte jesti, a njihove strvine držite za odvratnost."},{"v":12,"t":"Sve, dakle, što je u vodi a nema peraja i ljusaka neka je za vas odvratno.”"},{"v":13,"t":"“Od ptica neka su vam ove odvratne i neka se ne jedu - odvratnost su: orao, orao strvinar i jastreb,"},{"v":14,"t":"tetrijeb i sokol bilo koje vrste;"},{"v":15,"t":"gavran svih vrsta;"},{"v":16,"t":"noj, kobac i galeb; lastavica svake vrste;"},{"v":17,"t":"sova, gnjurac, ušara,"},{"v":18,"t":"labud, pelikan, droplja;"},{"v":19,"t":"roda, čaplja svake vrste; pupavac i šišmiš.”"},{"v":20,"t":"“Svi krilati kukci što hodaju četveronoške neka su vam odvratni!"},{"v":21,"t":"Od svih tih krilatih kukaca što hodaju četveronoške možete jesti samo one koji imaju na svojim nožicama listove za skakutanje po zemlji."},{"v":22,"t":"Od njih možete jesti: svaku vrstu skakavaca, cvrčaka i zrikavaca."},{"v":23,"t":"A svi drugi krilati kukci na četiri nožice neka su vam odvratni!"},{"v":24,"t":"I od njih ćete se onečistiti: tko se god dotakne njihove crkotine, neka je nečist do večeri;"},{"v":25,"t":"tko god ponese crkotinu bilo koje od njih, neka opere svoju odjeću i nečistim se smatra do večeri;"},{"v":26,"t":"i životinje s nerazdvojenim papkom što ne preživaju za vas su nečiste, i tko ih se dotakne neka je nečist!"},{"v":27,"t":"Onda, četveronožne životinje koje hodaju na četiri šape za vas su nečiste. Tko se dotakne njihova strva, neka je nečist do večeri."},{"v":28,"t":"A onaj koji ponese njihov strv, neka opere svoju odjeću i bude nečist do večeri. Za vas su one nečiste.”"},{"v":29,"t":"“Od životinja što po zemlji gmižu neka su za vas ove nečiste: krtica, miš i svaka vrsta guštera;"},{"v":30,"t":"zidni macaklin, kameleon, daždevnjak, zelembać i tinšamet."},{"v":31,"t":"Te su životinje od svih što gmižu za vas nečiste. Tko ih se mrtvih dotakne neka je nečist do večeri."},{"v":32,"t":"A na što koja od njih mrtva padne, neka je onečišćeno: bio to kakav drveni predmet ili odjeća, koža ili vreća. Svaki takav predmet koji se upotrebljava neka se zamoči u vodu i ostane nečist do večeri. Onda će postati čist."},{"v":33,"t":"Upadne li što od njih u kakvu zemljanu posudu, razbijte je; sve je u njoj onečišćeno."},{"v":34,"t":"A bilo kakva hrana što se jede, ako na nju kapne voda iz te posude, bit će onečišćena. Svaka tekućina što se pije u svakoj takvoj posudi neka se smatra nečistom."},{"v":35,"t":"A sve na što padne bilo što od njihove crkotine neka je nečisto; bude li to peć ili ognjište, neka se sruše: onečišćeni su za vas i neka nečisti budu."},{"v":36,"t":"A vrelo ili čatrnja koja drži vodu neka se smatraju čistima. Ali tko dirne strvinu životinje neka je nečist."},{"v":37,"t":"Ako što od njihova strva padne na žitno sjemenje što će se sijati, ono ostaje čisto;"},{"v":38,"t":"ali ako se sjemenje nakvasi vodom, a onda na nj padne što od njihove crkotine, neka je za vas nečisto."},{"v":39,"t":"Ako ugine koja životinja što vam služi za hranu, onaj koji dotakne njezinu strvinu neka je nečist do večeri;"},{"v":40,"t":"a koji pojede od njezine strvine neka opere svoju odjeću i bude nečist do večeri; koji ponese njezinu strvinu neka opere svoju odjeću i bude nečist do večeri."},{"v":41,"t":"Svaka životinja što po tlu gmiže odvratna je. Neka se ne jede!"},{"v":42,"t":"Ništa što puže na trbuhu, ništa što god ide na četiri noge ili na više nogu - nikakve puzavce što po tlu gmižu nemojte jesti jer su odvratni!"},{"v":43,"t":"Nemojte sami sebe poganiti svim tim puzavcima što gmižu; ne prljajte se njima, da i vi zbog njih ne postanete nečisti."},{"v":44,"t":"Ta ja - Jahve - Bog sam vaš! Posvećujte se, dakle, da sveti budete, jer svet sam ja! Nijednim se puzavcem što po tlu gmiže ne prljajte!"},{"v":45,"t":"Jest, ja sam Jahve; izveo sam vas iz zemlje egipatske da vam budem Bog. Budite, dakle, sveti jer sam svet ja!”"},{"v":46,"t":"To je odredba koja se odnosi na ptice i sva živa bića što se u vodi kreću i na sve stvorove koji po zemlji gmižu."},{"v":47,"t":"Svrha joj je da se razlikuje nečisto od čistoga; životinja koja se može jesti od životinje koja se ne smije jesti."}]},"12":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Kaži Izraelcima: 'Kad koja žena zatrudni i rodi muško čedo, neka je nečista sedam dana, kako je nečista u vrijeme svoga mjesečnog pranja."},{"v":3,"t":"Osmoga dana neka se dijete obreže."},{"v":4,"t":"A ona neka ostane još trideset i tri dana da se očisti od svoje krvi; ne smije dirati ništa posvećeno niti dolaziti u Svetište dok se ne navrši vrijeme njezina čišćenja."},{"v":5,"t":"Ako rodi žensko čedo, neka je nečista dva tjedna, kao za svoga mjesečnog pranja, i neka ostane još šezdeset i šest dana da se očisti od svoje krvi."},{"v":6,"t":"A kad se navrši vrijeme njezina čišćenja - bilo za sinčića, bilo za kćerkicu - neka donese svećeniku na ulaz u Šator sastanka jednogodišnje janje za žrtvu paljenicu i jednoga golubića ili grlicu za žrtvu okajnicu."},{"v":7,"t":"Neka on to prinese pred Jahvom i nad njom izvrši obred pomirenja. Tako će ona biti očišćena od svoga krvarenja. To je odredba koja se odnosi na ženu kad rodi bilo muško bilo žensko čedo."},{"v":8,"t":"Ali ako ne može da nađe dovoljno sredstava za grlo od sitnoga stada, neka onda uzme dvije grlice ili dva golubića - jedno za žrtvu paljenicu, a drugo za žrtvu okajnicu. Neka svećenik izvrši nad njom obred pomirenja, i ona će biti očišćena'.”"}]},"13":{"hr":[{"v":1,"t":"Reče Jahve Mojsiju i Aronu:"},{"v":2,"t":"“Ako se kome na koži pojavi oteklina ili lišaj ili bjelkasta pjega što bi bila nagovještaj gube na koži njegova tijela, neka se takav dovede svećeniku Aronu ili kojemu od njegovih sinova svećenika."},{"v":3,"t":"Neka svećenik pregleda zaraženo mjesto na koži njegova tijela. Ako je dlaka na zaraženom mjestu postala bijela i učini se da je ono dublje od kože njegova tijela, onda je to guba. Pošto ga svećenik pregleda, neka ga proglasi nečistim."},{"v":4,"t":"Ali ako se pokaže da bjelkasta pjega na koži njegova tijela nije dublja nego i koža, a dlaka na njoj nije pobijeljela, neka onda svećenik bolesnika osami sedam dana."},{"v":5,"t":"Neka ga sedmoga dana opet svećenik pregleda. Ako ustanovi svojim očima da zaraza još postoji, ali da se po koži dalje ne širi, neka ga osami još sedam dana."},{"v":6,"t":"Sedmoga dana neka ga opet pregleda. Bude li zaraženo mjesto manje upadno, a bolest se kožom ne bude proširila, neka ga proglasi čistim: to je samo lišaj. Pošto opere svoje haljine, bit će čist."},{"v":7,"t":"Ali ako se lišaj kožom proširi, pošto je svećenik bolesnika pregledao i proglasio ga čistim, neka se ponovo pokaže svećeniku."},{"v":8,"t":"Neka ga svećenik pregleda. Bude li se lišaj proširio po koži, neka ga svećenik proglasi nečistim: to je guba."},{"v":9,"t":"Ako se na čovjeku pokaže guba, neka ga dovedu svećeniku."},{"v":10,"t":"Neka ga svećenik pregleda. Ako po koži bude bjelkasta oteklina s pobijeljelom dlakom i napetim čirom,"},{"v":11,"t":"to je duboko ukorijenjena guba po koži njegova tijela. Neka ga svećenik proglasi nečistim. Ne treba ga osamljivati, jer je sigurno nečist."},{"v":12,"t":"Ako guba izbije po koži tako da bolesniku prekrije svu kožu od glave do pete - sve što svećenikove oči vide -"},{"v":13,"t":"neka svećenik obavi pregled. Bude li guba prekrila sve njegovo tijelo, neka ga proglasi čistim. Budući da je sav pobijelio, čist je."},{"v":14,"t":"Ali onog dana kad se na njemu pokaže čir, bit će nečist."},{"v":15,"t":"Kad svećenik vidi taj čir, neka bolesnika proglasi nečistim: čir je nečista stvar, to je guba."},{"v":16,"t":"Ali ako se čir promijeni u bijelo, neka čovjek dođe k svećeniku."},{"v":17,"t":"Svećenik neka ga pregleda. Bude li rana postala bijela, neka svećenik proglasi bolesnika čistim - čist i jest.”"},{"v":18,"t":"“Kad se kome na koži napne čir i zacijeli,"},{"v":19,"t":"i ondje gdje je bio čir pojavi se bjelkasta oteklina ili mjesto izblijedi i postane bjelkasto, ili izbije bijelocrvenkasta pjega, neka se taj čovjek pokaže svećeniku."},{"v":20,"t":"Neka ga svećenik pregleda. Pronađe li da je tu koža udubljenija a dlaka pobijeljela, neka ga svećenik proglasi nečistim - to je onda guba što je izbila u čiru."},{"v":21,"t":"Ali ako svećenik ustanovi da tu dlaka nije pobijeljela, da koža nije udubljenija nego drugdje, da mjesto tamni, neka bolesnika osami sedam dana."},{"v":22,"t":"Proširi li mu se bolest po koži, neka ga svećenik proglasi nečistim - to je guba."},{"v":23,"t":"Ako pjega ostane na mjestu i ne proširi se, to je ožiljak od čira. Neka toga čovjeka svećenik proglasi čistim.”"},{"v":24,"t":"“Kome na koži bude opeklina, pa mjesto opekline postane pjega bijelocrvenkasta ili bjelkasta,"},{"v":25,"t":"neka to svećenik pregleda. Ako dlaka na mjestu bude pobijeljela i učini se da je to mjesto udubljenije od kože, onda je to guba što je u opeklini izbila. Neka ga svećenik proglasi nečistim; to je guba."},{"v":26,"t":"Ali ako svećenik ustanovi da dlaka nije pobijeljela, da mjesto nije udubljenije od kože i da tamni, neka ga osami sedam dana."},{"v":27,"t":"Sedmoga dana neka ga pregleda. Ako se pjega po koži proširi, neka ga svećenik proglasi nečistim: to je guba."},{"v":28,"t":"Ostane li ozljeda na mjestu i proširi se po koži, to je onda oteklina od opekline. Neka čovjeka svećenik proglasi čistim: to je ožiljak od opekline.”"},{"v":29,"t":"“Ako se na glavi ili na bradi kojega čovjeka ili žene pokaže bolest,"},{"v":30,"t":"neka svećenik bolest pregleda. Ustanovi li se da je dublje od kože i da je tu dlaka požutjela i otančala, neka bolesnika svećenik proglasi nečistim. To je šuga, to jest guba na glavi ili na bradi."},{"v":31,"t":"Ali ako svećenik, pregledavši oboljelo mjesto, ustanovi da nije dublje od kože, ali da tu ipak nema crne dlake, neka svećenik odstrani šugavca sedam dana."},{"v":32,"t":"Sedmoga dana neka ga svećenik pregleda. Ako se šuga nije proširila niti dlaka požutjela, te ako se čini da šuga nije dublja od kože,"},{"v":33,"t":"neka se bolesnik obrije - ali ošugano mjesto da ne brije! - i neka ga svećenik odstrani od drugih sedam dana."},{"v":34,"t":"Sedmoga dana neka opet svećenik pregleda šugavo mjesto. Ako se šuga kožom ne bude proširila i učini se da nije dublja od kože, neka tog bolesnika svećenik proglasi čistim. On neka opere svoju odjeću i bude čist."},{"v":35,"t":"Proširi li se šuga po koži pošto je bio čistim proglašen,"},{"v":36,"t":"neka ga svećenik ponovo pregleda. Ako se šuga kožom bude proširila - svećenik neka više i ne traži žute dlake - bolesnik ja nečist."},{"v":37,"t":"Ali ako opazi da je šuga stala i da je nikla crna dlaka, šuga je zacijeljela - on je čist. Neka ga svećenik proglasi čistim.”"},{"v":38,"t":"“Ako se na koži kojeg čovjeka ili žene pokažu pjege te ako su te pjege bijele,"},{"v":39,"t":"neka ih svećenik pregleda. Ako te pjege po koži budu tamnobijele, onda je to osip što je izbio po koži: bolesnik je čist.”"},{"v":40,"t":"“Ako čovjeku opadne kosa s glave, oćelavio mu je zatiljak, ali je čist."},{"v":41,"t":"Ako mu sprijeda opadne kosa s glave, oćelavio je na čelu, ali je čist."},{"v":42,"t":"Ali ako se po ćelavu zatiljku ili po oćelavljelu čelu pojavi crvenkastobijela bolest, to je guba što je izbila po njegovu ćelavom zatiljku ili oćelavljelu čelu."},{"v":43,"t":"Neka ga svećenik pregleda. Ako ustanovi da je osip na ćelavu zatiljku ili po oćelavljelu čelu bjelkastocrvenkast - naizgled kao i guba na koži tijela -"},{"v":44,"t":"čovjek se ogubavio, nečist je. Svećenik ga mora proglasiti nečistim - guba mu je na glavi.”"},{"v":45,"t":"“Onaj koji se bude ogubavio, neka nosi rasparanu odjeću; kosa neka mu je raščupana; gornju usnu neka prekrije i viče: “Nečist! Nečist!”"},{"v":46,"t":"Sve dok na njemu bude bolest, neka nečistim ostane, a kako je nečist, neka stanuje nasamo: neka mu je stan izvan tabora.”"},{"v":47,"t":"“Kad se zaraza gube pokaže na odijelu, bilo vunenu bilo lanenu,"},{"v":48,"t":"na osnovi ili na potki od lana ili vune; ili na koži; ili na bilo kakvu predmetu od kože;"},{"v":49,"t":"pa ako mrlja na odijelu ili koži, na osnovi ili na potki, ili na bilo kakvu predmetu od kože, bude zelenkasta ili crvenkasta, to je guba i neka se svećeniku pokaže."},{"v":50,"t":"Neka svećenik, pošto pregleda što je zaraženo, to stavi na osamu sedam dana."},{"v":51,"t":"Onda neka sedmoga dana zarazu pregleda. Ako se zaraza proširi po odijelu, po osnovi ili potki, ili po koži, ili po kakvu god predmetu od kože, to je zarazna guba. Stvar je nečista."},{"v":52,"t":"To odijelo - bilo osnova bilo potka, od vune ili lana - ili kakav kožni predmet za koji je zaraza prionula, gubom se zarazio; neka na vatri izgori."},{"v":53,"t":"Ali ako svećenik opazi da se zaraza nije proširila na odijelu - na osnovi ni na potki - niti na bilo kakvu kožnom predmetu,"},{"v":54,"t":"onda neka naredi da se zaražena stvar opere. Neka je zatim stavi nasamo drugih sedam dana."},{"v":55,"t":"A ako, pošto je stvar bila oprana, svećenik opazi da se zaraženo mjesto nije promijenilo, ipak, mada se bolest nije raširila, stvar je nečista. Neka se na vatri spali: trula je i iznutra i izvana."},{"v":56,"t":"Opazi li svećenik da se bolest smanjuje nakon pranja, neka to mjesto izreže, bilo ono na odijelu ili na koži, na osnovi ili na potki."},{"v":57,"t":"Ako se na odijelu opet pojavi, u osnovi ili potki, ili bilo kakvu kožnom predmetu, onda je to zaraza, i zaraženi predmet neka u vatri izgori."},{"v":58,"t":"Ako li bolest nestane s odijela - osnove ili potke - ili bilo kakva kožnoga predmeta pošto je bio opran, neka se opere opet, pa neka je čist.”"},{"v":59,"t":"To su propisi za bolest gube na odijelu od vune ili lana - u osnovi ili potki - ili bilo kakvu predmetu od kože da se proglase čistim ili nečistim."}]},"14":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Neka ovo bude obred za gubavca na dan njegova čišćenja: neka se dovede svećeniku;"},{"v":3,"t":"neka svećenik iziđe iz tabora i obavi pregled. Ako ustanovi da je gubavac od gube ozdravio,"},{"v":4,"t":"neka naredi da se za čovjeka koji se ima čistiti uzmu dvije ptice, čiste i žive, cedrovine, grimiznog prediva i izopa."},{"v":5,"t":"Neka zatim svećenik naredi da se jedna ptica zakolje nad živom vodom u zemljanoj posudi."},{"v":6,"t":"Potom neka uzme živu pticu, a onda zajedno živu pticu, cedrovinu, grimizno predivo i izop zamoči u krv ptice što je bila zaklana povrh žive vode."},{"v":7,"t":"Sada neka sedam puta poškropi onoga koji se od gube čisti, a onda ga čistim proglasi. Poslije toga neka pusti živu pticu na otvorenu polju."},{"v":8,"t":"Onaj koji se čisti neka opere svoju odjeću, obrije sve svoje dlake i u vodi se okupa. Tako neka je čist. Poslije toga neka uđe u tabor, ali sedam dana neka stanuje izvan svoga šatora."},{"v":9,"t":"Sedmi dan neka obrije sve svoje dlake: kosu, bradu i obrve; neka obrije sve ostale svoje dlake. Pošto u vodi opere svoju odjeću i okupa se, neka je čist."},{"v":10,"t":"Osmoga dana neka uzme muško janje bez mane, jedno žensko janje od godine dana, također bez mane, tri desetine efe najboljeg brašna zamiješena u ulju za žrtvu prinosnicu i jedan log ulja."},{"v":11,"t":"Svećenik koji vrši čišćenje neka ih stavi pred Jahvu na ulazu u Šator sastanka s čovjekom koji se ima čistiti."},{"v":12,"t":"Neka zatim svećenik uzme jedno muško janje pa ga s ono ulja u logu prinese kao žrtvu naknadnicu. Neka ih prinese pred Jahvom kao žrtvu prikaznicu."},{"v":13,"t":"Neka janje zakolje ondje gdje se kolju žrtve okajnice i žrtve paljenice - na svetome mjestu, jer žrtva naknadnica kao i okajnica pripada svećeniku: vrlo je sveta!"},{"v":14,"t":"Potom neka svećenik uzme krvi od žrtve naknadnice, pa neka njome namaže resicu desnoga uha, palac desne ruke i palac desne noge onoga koji se čisti."},{"v":15,"t":"Poslije toga neka uzme log s uljem i izlije na dlan svoje lijeve ruke."},{"v":16,"t":"Zamočivši svećenik svoj desni prst u ulje na svojoj lijevoj ruci, neka uljem sa svoga prsta obavi škropljenje pred Jahvom sedam puta."},{"v":17,"t":"Od ulja što mu preostane u ruci neka svećenik, po krvi od žrtve naknadnice, pomaže resicu desnoga uha, palac desne ruke i palac desne noge onoga koji se čisti."},{"v":18,"t":"Ostatak ulja sa svoje ruke neka svećenik metne na glavu onoga koji se čisti. Tako će svećenik nad njim izvršiti obred pomirenja pred Jahvom."},{"v":19,"t":"Neka svećenik poslije toga prinese žrtvu okajnicu i nad onim koji se čisti neka obavi obred pomirenja za njegovu nečistoću. Napokon neka zakolje žrtvu paljenicu,"},{"v":20,"t":"a onda neka svećenik žrtvu paljenicu i žrtvu prinosnicu podigne na žrtvenik. Kad tako svećenik nad njim obavi obred pomirenja, neka je čist."},{"v":21,"t":"Ako bude siromašan te ne mogne to priskrbiti, neka uzme samo jedno muško janje za žrtvu naknadnicu i neka se ono prinese kao žrtva prinosnica da se nad tim čovjekom izvrši obred pomirenja. I neka uzme samo desetinu efe najboljeg brašna zamiješena u ulju za žrtvu prinosnicu, jedan log ulja,"},{"v":22,"t":"k tome dvije grlice ili dva golubića - prema svojim mogućnostima - jedno za žrtvu okajnicu, a drugo za žrtvu paljenicu."},{"v":23,"t":"Osam dana nakon svoga očišćenja neka ih donese svećeniku na ulaz u Šator sastanka pred Jahvu."},{"v":24,"t":"Neka svećenik uzme janje za žrtvu naknadnicu i log s uljem pa ih prinese pred Jahvom kao žrtvu prikaznicu."},{"v":25,"t":"Neka se onda zakolje janje žrtve naknadnice, a svećenik neka uzme njegove krvi i neka njome namaže resicu desnoga uha, palac desne ruke i palac desne noge onoga koji se čisti."},{"v":26,"t":"Poslije toga neka svećenik izlije ulje na dlan svoje lijeve ruke."},{"v":27,"t":"A onda neka od ulja što mu je na dlanu lijeve ruke obavi škropljenje sedam puta prstom svoje desne ruke pred Jahvom."},{"v":28,"t":"Od ulja iz svoje ruke neka svećenik, po krvi žrtve naknadnice, namaže resicu desnog uha, palac desne ruke i palac desne noge onoga koji se čisti."},{"v":29,"t":"Ostatak ulja što bude na dlanu neka svećenik stavi na glavu onoga koji se čisti, vršeći nad njim obred pomirenja pred Jahvom."},{"v":30,"t":"Neka zatim prinese jednu od dviju grlica ili jednoga od dvaju golubića - što je već mogao pribaviti -"},{"v":31,"t":"kao žrtvu okajnicu, a drugu kao žrtvu paljenicu zajedno sa žrtvom prinosnicom. Neka tako svećenik izvrši obred pomirenja pred Jahvom nad onim koji se čisti.”"},{"v":32,"t":"To je propis za onoga koji je gubom zaražen a ne može priskrbiti sve za svoje očišćenje."},{"v":33,"t":"Jahve reče Mojsiju i Aronu:"},{"v":34,"t":"“Kad uđete u kanaansku zemlju koju ću vam dati u posjed, a ja pustim gubu na koju kuću u zemlji što je budete zaposjeli,"},{"v":35,"t":"onda onaj čija je kuća neka dođe svećeniku i kaže: 'Čini mi se da je moja kuća zaražena gubom.'"},{"v":36,"t":"Neka svećenik naredi da se kuća isprazni prije nego on dođe da bolest pregleda, da ne bi sve što je u kući bilo proglašeno nečistim; poslije toga neka svećenik uđe da kuću pregleda."},{"v":37,"t":"Ako nakon pregleda zapazi da je bolest na kućnim zidovima od zelenkastih ili crvenkastih udubina i pričini mu se da idu dublje od površine zida,"},{"v":38,"t":"neka svećenik iziđe iz kuće na kućna vrata i neka kuću zatvori sedam dana."},{"v":39,"t":"Sedmi dan neka svećenik opet dođe i pregleda: ako se bolest bude proširila po zidovima kuće,"},{"v":40,"t":"neka svećenik naredi da se povadi zaraženo kamenje i baci na koje nečisto mjesto izvan grada."},{"v":41,"t":"Zatim neka zapovjedi da se svi unutarnji zidovi kuće ostružu i da se sastrugani prah baci na koje nečisto mjesto izvan grada."},{"v":42,"t":"Onda neka se uzme drugo kamenje i umetne namjesto onoga kamenja. Potom neka se uzme druga žbuka i kuća ponovo ožbuka."},{"v":43,"t":"Ako se pošast na kući opet pojavi pošto je kamenje bilo povađeno i kuća ostrugana i opet ožbukana,"},{"v":44,"t":"neka svećenik ode da pregleda: bude li se bolest po kući proširila, to je onda u kući zarazna guba; kuća je nečista."},{"v":45,"t":"Neka se kuća poruši, a njezino kamenje, njezina drvena građa i sva žbuka s kuće neka se odnese izvan grada na koje nečisto mjesto."},{"v":46,"t":"Tko uđe u kuću dok je zatvorena, neka je nečist do večeri."},{"v":47,"t":"Tko u kući legne, mora oprati svoju odjeću. I tko u kući objeduje, mora svoju odjeću oprati."},{"v":48,"t":"Ako li svećenik dođe i vidi da se bolest po kući nije proširila pošto je kuća opet bila ožbukana, neka svećenik kuću proglasi čistom, jer se bolest izliječila."},{"v":49,"t":"A za očišćenje kuće neka uzme: dvije ptice, cedrovine, grimizna prediva i izopa."},{"v":50,"t":"Jednu od ptica neka zakolje nad živom vodom u zemljanoj posudi."},{"v":51,"t":"Potom neka uzme: cedrovinu, izop, grimizno predivo i pticu živu te ih zamoči u krv ptice zaklane i u živu vodu pa kuću poškropi sedam puta."},{"v":52,"t":"Očistivši tako od grijeha kuću krvlju ptice, živom vodom, živom pticom, cedrovinom, izopom i grimiznim predivom,"},{"v":53,"t":"neka pticu živu pusti izvan grada na otvorenu polju. Kad tako obavi obred pomirenja nad kućom, bit će čista.”"},{"v":54,"t":"To je propis za svaku vrst gube i šuge,"},{"v":55,"t":"za gubu odjeće ili kuće,"},{"v":56,"t":"za otekline, lišaje ili pjege."},{"v":57,"t":"On određuje vrijeme nečistoće i čistoće. To je zakon o gubi."}]},"15":{"hr":[{"v":1,"t":"Jahve reče Mojsiju i Aronu:"},{"v":2,"t":"“Govorite Izraelcima i kažite im: 'Kad koji čovjek imadne izljev iz svoga tijela, njegov je izljev nečist."},{"v":3,"t":"Evo u čemu je njegova nečistoća ako ima taj izljev: ispusti li njegovo tijelo izljev ili ga zadrži, on je nečist."},{"v":4,"t":"Svaka postelja na koju legne onaj koji ima izljev neka je nečista; i svaki predmet na koji sjedne neka je nečist."},{"v":5,"t":"A svaki koji se dotakne njegove posteljine neka opere svoju odjeću, u vodi se okupa i nečistim ostane do večeri."},{"v":6,"t":"Tko god sjedne na predmet na kojemu je sjedio onaj koji je imao izljev neka opere svoju odjeću, u vodi se okupa i nečistim ostane do večeri."},{"v":7,"t":"Tko se dotakne tijela onoga koji je imao izljev neka opere svoju odjeću, u vodi se okupa i do večeri nečistim ostane."},{"v":8,"t":"Ako onaj koji ima izljev pljune na koga tko je čist neka taj opere svoju odjeću, u vodi se okupa i nečistim ostane do večeri."},{"v":9,"t":"Neka je nečisto i svako sjedalo na koje za vožnje sjedne onaj koji ima izljev;"},{"v":10,"t":"i tko se dotakne čega što je pod tim bolesnikom bilo neka je nečist do večeri. Tko ponese štogod takvo neka svoju odjeću opere, u vodi se okupa i ostane nečistim do večeri."},{"v":11,"t":"A svaki koga se onaj koji ima izljev dotakne neopranih ruku neka svoju odjeću opere, u vodi se okupa i ostane nečistim do večeri."},{"v":12,"t":"Zemljana posuda koje se dotakne onaj s izljevom neka se razbije, a svaki drveni sud neka se vodom ispere."},{"v":13,"t":"Kad se onaj koji ima izljev od toga izliječi, neka onda nabroji sedam dana za svoje oćišćenje; neka opere svoju odjeću, okupa se u živoj vodi i neka je čist."},{"v":14,"t":"Osmoga pak dana neka uzme dvije grlice ili dva golubića, dođe pred Jahvu na ulaz u Šator sastanka pa ih svećeniku preda."},{"v":15,"t":"Neka ih svećenik prinese jedno kao žrtvu okajnicu, a drugo kao žrtvu paljenicu. Time će svećenik izvršiti obred pomirenja nad tim čovjekom za njegov izljev."},{"v":16,"t":"Kad čovjek imadne sjemeni izljev, neka u vodi okupa cijelo svoje tijelo i ostane nečistim do večeri."},{"v":17,"t":"Svaka haljina i svaka koža na koju dospije takav sjemeni izljev neka se u vodi opere i ostane nečistom do večeri."},{"v":18,"t":"Ako koja žena legne s kojim čovjekom i on ispusti sjeme, neka se okupaju u vodi i budu nečisti do večeri'.”"},{"v":19,"t":"“Kad žena imadne krvarenje, izljev krvi iz svoga tijela, neka ostane u svojoj nečistoći sedam dana; tko se god nje dotakne neka je nečist do večeri."},{"v":20,"t":"Na što god bi legla za svoje nečistoće neka je nečisto; na što god sjedne neka je nečisto."},{"v":21,"t":"Tko se dotakne njezine posteljine neka opere svoju odjeću, u vodi se okupa i do večeri ostane nečistim."},{"v":22,"t":"Tko god dotakne bilo koji predmet na kojemu je ona sjedila neka svoju odjeću opere, u vodi se okupa i nečist ostane do večeri."},{"v":23,"t":"A ako bi se dotakao čega što je bilo na njezinoj postelji ili na predmetu na kojem je ona sjedila, neka je nečist do večeri."},{"v":24,"t":"Ako koji čovjek s njom legne, njezina nečistoća za nj prianja, pa neka je nečist sedam dana. Svaka postelja na koju on legne neka je nečista."},{"v":25,"t":"Ako žena imadne krvarenje dulje vremena izvan svoga mjesečnog pranja, ili ako se njezino mjesečno pranje produžuje, neka se smatra nečistom sve vrijeme krvarenja kao da su dani njezina mjesečnog pranja."},{"v":26,"t":"Svaka postelja na koju legne za sve vrijeme svoga krvarenja bit će joj kao i postelja za njezina mjesečnog pranja. I svaki predmet na koji sjedne neka postane nečistim kao što bi bio nečist u vrijeme njezina mjesečnog pranja."},{"v":27,"t":"A svatko tko ih se dotakne neka je nečist; neka opere svoju odjeću, okupa se u vodi i ostane nečistim do večeri."},{"v":28,"t":"Ako ozdravi od svog krvarenja, neka namiri sedam dana, a poslije toga neka je čista."},{"v":29,"t":"Osmoga dana neka uzme dvije grlice ili dva golubića te ih donese svećeniku na ulaz u Šator sastanka."},{"v":30,"t":"Neka jedno svećenik prinese kao žrtvu okajnicu, a drugo kao žrtvu paljenicu. Tako će svećenik obaviti pred Jahvom obred pomirenja nad njom, za njezino nečisto krvarenje.”"},{"v":31,"t":"“Odvraćajte Izraelce od njihovih nečistoća, da ne bi zbog njih pomrli oskvrnjujući moje Prebivalište koje se nalazi među njima."},{"v":32,"t":"To je propis za čovjeka koji ima izljev; za onoga koga čini nečistim sjemeni izljev;"},{"v":33,"t":"za ženu u vrijeme nečistoće njezina mjesečnog pranja; za svakoga - bilo muško bilo žensko - tko imadne izljev, a tako i za čovjeka koji legne s onečišćenom ženom.”"}]},"16":{"hr":[{"v":1,"t":"Poslije smrti dvojice Aronovih sinova, koji su poginuli prinoseći pred Jahvom neposvećenu vatru, progovori Jahve Mojsiju."},{"v":2,"t":"Jahve reče Mojsiju: “Kaži svome bratu Aronu da ne ulazi u svako doba u Svetište iza zavjese, pred Pomirilište koje se nalazi na Kovčegu, da ne pogine. Jer ja ću se pojavljivati nad Pomirilištem u oblaku."},{"v":3,"t":"Neka Aron ulazi u Svetište ovako: s juncem za žrtvu okajnicu i ovnom za žrtvu paljenicu."},{"v":4,"t":"Neka se obuče u posvećenu košulju od lana; na svoje tijelo neka navuče gaće od lana; neka se opaše lanenim pasom, a na glavu stavi mitru od lana. To je posvećeno ruho koje ima obući pošto se okupa u vodi."},{"v":5,"t":"Od zajednice izraelske neka primi dva jarca za žrtvu okajnicu i jednoga ovna za žrtvu paljenicu."},{"v":6,"t":"Pošto Aron prinese junca za žrtvu okajnicu za svoj grijeh i izvrši obred pomirenja za se i za svoj dom,"},{"v":7,"t":"neka uzme oba jarca i postavi ih pred Jahvu na ulaz u Šator sastanka."},{"v":8,"t":"Neka Aron baci kocke za oba jarca te jednoga odredi kockom Jahvi, a drugoga Azazelu."},{"v":9,"t":"Jarca na kojega je kocka pala da bude Jahvi neka Aron prinese za žrtvu okajnicu."},{"v":10,"t":"A jarac na kojega je kocka pala da bude Azazelu neka se smjesti živ pred Jahvu, da se nad njim obavi obred pomirenja i otpremi Azazelu u pustinju."},{"v":11,"t":"Zatim neka Aron prinese junca za žrtvu okajnicu za svoj grijeh; i obavi obred pomirenja za se i za svoj dom: i neka zakolje toga junca za žrtvu okajnicu za svoj grijeh."},{"v":12,"t":"Potom neka uzme kadionik pun užarena ugljevlja sa žrtvenika ispred Jahve i dvije pune pregršti miomirisnoga tamjana u prah smrvljenoga. Neka to unese iza zavjese."},{"v":13,"t":"Sad neka stavi tamjan na vatru pred Jahvom da oblak od tamjana zastre Pomirilište što je na Svjedočanstvu. Tako neće poginuti."},{"v":14,"t":"Poslije toga neka uzme krvi od junca i svojim prstom poškropi istočnu stranu Pomirilišta; a ispred Pomirilišta neka svojim prstom poškropi sedam puta tom krvlju."},{"v":15,"t":"Neka potom zakolje jarca za žrtvu okajnicu za grijeh naroda; neka unese njegovu krv za zavjesu te s njegovom krvi učini kako je učinio s krvlju od junca: neka njome poškropi po Pomirilištu i pred njim."},{"v":16,"t":"Tako će obaviti obred pomirenja nad Svetištem zbog nečistoća Izraelaca, zbog njihovih prijestupa i svih njihovih grijeha. A tako neka učini i za Šator sastanka što se među njima nalazi, sred njihovih nečistoća."},{"v":17,"t":"Kad on uđe da obavi obred pomirenja u Svetištu, neka nikoga drugog ne bude u Šatoru sastanka dok on ne iziđe. Obavivši obred pomirenja za se, za svoj dom i za svu izraelsku zajednicu,"},{"v":18,"t":"neka ode k žrtveniku koji se nalazi pred Jahvom te nad žrtvenikom obavi obred pomirenja. Neka uzme krvi od junca i krvi od jarca pa stavi na rogove oko žrtvenika."},{"v":19,"t":"Neka svojim prstom poškropi žrtvenik istom krvlju sedam puta. Tako će ga očistiti od nečistoća Izraelaca i posvetiti."},{"v":20,"t":"Kad svrši obred pomirenja Svetišta, Šatora sastanka i žrtvenika, neka primakne jarca živoga."},{"v":21,"t":"Neka mu na glavu Aron stavi obje svoje ruke i nad njim ispovjedi sve krivnje Izraelaca, sve njihove prijestupe i sve njihove grijehe. Položivši ih tako jarcu na glavu, neka ga pošalje u pustinju s jednim prikladnim čovjekom."},{"v":22,"t":"Tako će jarac na sebi odnijeti sve njihove krivnje u pusti kraj. Otpremivši jarca u pustinju,"},{"v":23,"t":"neka se Aron vrati u Šator sastanka, sa sebe svuče lanenu odjeću u koju se bio obukao kad je ulazio u Svetište i neka je ondje ostavi."},{"v":24,"t":"Neka potom opere svoje tijelo vodom na posvećenu mjestu, na se obuče svoju odjeću te iziđe da prinese svoju žrtvu paljenicu i žrtvu paljenicu naroda i obavi obred pomirenja za se i za narod."},{"v":25,"t":"Loj sa žrtve okajnice neka sažeže u kad na žrtveniku."},{"v":26,"t":"Onaj koji je odveo jarca Azazelu neka opere svoju odjeću, svoje tijelo u vodi okupa i poslije toga može opet doći u tabor."},{"v":27,"t":"A junca žrtve okajnice i jarca žrtve okajnice od kojih je krv bila donesena u Svetište da se obavi obred pomirenja neka odnesu izvan tabora pa neka na vatri spale njihove kože, njihovo meso i njihovu nečist."},{"v":28,"t":"Tko ih bude spaljivao, neka opere svoju odjeću, svoje tijelo okupa u vodi i poslije toga može opet doći u tabor."},{"v":29,"t":"Ovaj zakon neka za vas trajno vrijedi. U sedmom mjesecu, deseti dan toga mjeseca, postite i ne obavljajte nikakva posla: ni domorodac ni stranac koji među vama boravi."},{"v":30,"t":"Jer toga dana nad vama se ima izvršiti obred pomirenja da se očistite od svih svojih grijeha te da pred Jahvom budete čisti."},{"v":31,"t":"Neka je to za vas subotnji počinak kad postite. Trajan je to zakon."},{"v":32,"t":"Neka obred pomirenja obavi onaj svećenik koji bude pomazan i posvećen za vršenje svećeničke službe namjesto svoga oca. Neka se obuče u posvećeno laneno ruho;"},{"v":33,"t":"on neka obavi obred pomirenja za posvećeno Svetište, za Šator sastanka i za žrtvenik. Zatim neka izvrši obred pomirenja nad svećenicima i nad svim narodom zajednice."},{"v":34,"t":"Tako neka to bude za vas trajan zakon; jednom na godinu neka se nad Izraelcima obavi obred pomirenja za sve njihove grijehe.” Mojsije je učinio kako mu je Jahve naredio."}]},"17":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Govori Aronu, njegovim sinovima i svima Izraelcima te im reci: 'Evo što je zapovjedio Jahve:"},{"v":3,"t":"svaki onaj od Izraelova doma koji u taboru ili izvan tabora zakolje vola, ili ovcu, ili kozu,"},{"v":4,"t":"a ne donese ih na ulaz u Šator sastanka da se prinesu na dar Jahvi pred njegovim Prebivalištem, svaki takav neka je odgovoran: prolio je krv i neka se odstrani iz svoga naroda.'"},{"v":5,"t":"Zato neka Izraelci svoje žrtve koje bi htjeli klati vani u polju dovedu na ulaz u Šator sastanka, k svećeniku, i neka ih prinose kao žrtve pričesnice."},{"v":6,"t":"Neka svećenik izlije krv po Jahvinu žrtveniku koji se nalazi na ulazu u Šator sastanka, a loj spali na ugodan miris Jahvi,"},{"v":7,"t":"tako da ubuduće ne prinose svojih žrtava klanica jarcima s kojima se odaju bludu. Neka je ovo trajan zakon za njih i njihove naraštaje."},{"v":8,"t":"I kaži im: 'Svaki pojedinac od Izraelova doma, ili stranac koji među vama boravi, koji prinese paljenicu ili klanicu"},{"v":9,"t":"a ne donese je na ulaz u Šator sastanka da se prinese Jahvi, taj neka se odstrani iz svoga naroda.'”"},{"v":10,"t":"“Nadalje, protiv svakoga pojedinca od Izraelova doma, a tako i protiv svakoga pridošlice među vama koji bi blagovao bilo kakvu krv, ja ću se okrenuti, svakoga tko blaguje krv odstranit ću iz njegova naroda."},{"v":11,"t":"Jer je život živoga bića u krvi. Tu krv ja sam vama dao da na žrtveniku njome obavljate obred pomirenja za svoje živote. Jer krv je ono što ispašta za život."},{"v":12,"t":"Zato sam kazao Izraelcima: neka nitko od vas ne jede krvi; neka ni stranac koji među vama bude ne jede krvi."},{"v":13,"t":"Tko god, Izraelac ili stranac koji među vama boravi, uhvati u lovu kakvu zvijer ili pticu što se može jesti neka joj prolije krv i zatrpa zemljom."},{"v":14,"t":"Jer život svakoga živog bića jest njegova krv. Zato sam i rekao Izraelcima: ne smijete jesti krvi ni od kakva živog bića, jer život svakoga živog bića jest njegova krv. Tko god je bude jeo, neka se odstrani."},{"v":15,"t":"Tko bi god, Izraelac ili stranac, jeo što je uginulo ili što su zvijeri rastrgale neka opere svoju odjeću, u vodi se okupa i ostane nečistim do večeri. Tada će postati čist."},{"v":16,"t":"Ali ako je ne opere i ne okupa svoga tijela, neka snosi posljedice svoje krivnje.”"}]},"18":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Govori Izraelcima i reci im: 'Ja sam Jahve, Bog vaš."},{"v":3,"t":"Nemojte raditi kako se radi u zemlji egipatskoj, gdje ste boravili; niti radite kako se radi u zemlji kanaanskoj, kamo vas vodim; ne povodite se za njihovim običajima!"},{"v":4,"t":"Vršite moje naredbe; vršite moje zapovijedi; prema njima hodite. Ja sam Jahve, Bog vaš."},{"v":5,"t":"Zato držite moje zakone i moje naredbe; tko ih vrši - u njima će naći život. Ja sam Jahve!"},{"v":6,"t":"Neka se nitko od vas ne približuje svojoj krvnoj rodbini da otkriva njezinu golotinju. Ja sam Jahve!"},{"v":7,"t":"Ne otkrivaj golotinje svoga oca ni golotinje svoje majke. Majka ti je, ne otkrivaj njezine golotinje!"},{"v":8,"t":"Ne otkrivaj golotinje žene svoga oca! I to je golotinja tvoga oca!"},{"v":9,"t":"Ne otkrivaj golotinje svoje sestre - kćeri svoga oca ili kćeri svoje majke - bila rođena u kući ili izvan nje!"},{"v":10,"t":"Ne otkrivaj golotinje kćeri svoga sina niti golotinje kćeri svoje kćeri! TÓa njihova je golotinja tvoja vlastita golotinja."},{"v":11,"t":"Ne otkrivaj golotinje kćeri žene svoga oca! Jer, rođena od tvog oca, ona ti je sestra."},{"v":12,"t":"Ne otkrivaj golotinje sestre svoga oca! Ona je krv tvoga oca."},{"v":13,"t":"Ne otkrivaj ni golotinje sestre svoje majke! Ta i ona je krv tvoje majke!"},{"v":14,"t":"Ne otkrivaj golotinje svoga strica! To jest, nemoj se približavati njegovoj ženi. Ta ona je tvoja strina."},{"v":15,"t":"Ne otkrivaj golotinje svoje snahe! Ona je žena tvoga sina. Ne otkrivaj golotinje njezine."},{"v":16,"t":"Ne otkrivaj golotinje žene svoga brata! Ta to je golotinja tvoga brata."},{"v":17,"t":"Ne otkrivaj golotinje koje žene i njezine kćeri! Nemoj se ženiti kćerju njezina sina niti kćerju njezine kćeri te im golotinju otkrivati. Oni su krvna rodbina. To bi bila pokvarenost."},{"v":18,"t":"Ne uzimaj sebi koju ženu u isto vrijeme kad i njezinu sestru da je ljubomorom žalostiš otkrivajući golotinju ovoj preko nje za njezina života!"},{"v":19,"t":"Ne približuj se ni jednoj ženi kad je u nečistoći svoga mjesečnog pranja da joj otkrivaš golotinju!"},{"v":20,"t":"Ne lijegaj sa ženom bližnjega svoga; od nje bi postao nečist."},{"v":21,"t":"Ne smiješ dopuštati da koje tvoje dijete bude žrtvovano Moleku; ne smiješ tako obeščašćivati ime Boga svoga. Ja sam Jahve!"},{"v":22,"t":"Ne lijegaj s muškarcem kako se liježe sa ženom! To bi bila grozota."},{"v":23,"t":"Da nisi legao ni s jednom životinjom - od nje bi postao nečist. Žena ne smije stati pred životinju da se s njom pari. To bi bila krajnja opačina."},{"v":24,"t":"Ničim se od toga nemojte onečišćavati! Ta svim su se tim onečišćavali narodi koje ja ispred vas tjeram."},{"v":25,"t":"I zemlja je postala nečista. Zato ću kazniti njezinu opačinu, i zemlja će ispljuvati svoje stanovnike."},{"v":26,"t":"Vi pak držite moje zakone i moje naredbe: ni jedne od tih opačina nemojte počinjati - ni vi ni stranac koji među vama boravi."},{"v":27,"t":"Sve je te zloće počinjao svijet koji je bio u toj zemlji prije vas te je zemlja postala nečista."},{"v":28,"t":"Neće li, ako je učinite nečistom, zemlja ispljuvati i vas kako je ispljuvala narod koji je bio prije vas?"},{"v":29,"t":"Jest, svi koji bi počinili bilo koju od tih zloća bit će odstranjeni iz svoga naroda."},{"v":30,"t":"Zato držite moje zapovijedi; nemojte se podavati ni jednome od onih odvratnih običaja što su se održavali prije vas; tako se njima nećete onečistiti. Ja sam Jahve, Bog vaš!'”"}]},"19":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Govori svoj zajednici Izraelaca i reci im: 'Sveti budite! Jer sam svet ja, Jahve, Bog vaš!"},{"v":3,"t":"Svoje se majke i svoga oca svaki bojte! Subote moje držite! Ja sam Jahve, Bog vaš!"},{"v":4,"t":"Ne obraćajte se na ništavila! Ne pravite sebi lijevanih kumira! Ja sam Jahve, Bog vaš!"},{"v":5,"t":"Kad prinosite Jahvi žrtvu pričesnicu, prinesite je tako da budete primljeni."},{"v":6,"t":"Neka se pojede na dan kad je prinosite ili sutradan. Što preostane za prekosutra neka se spali na vatri."},{"v":7,"t":"Kad bi se jelo od toga jela treći dan, bilo bi odvratno i žrtva ne bi bila primljena."},{"v":8,"t":"A onaj koji je ipak jede neka snosi posljedice svoje krivnje. Budući da je oskvrnuo ono što je Jahvi posvećeno, neka se takav odstrani iz svoga naroda."},{"v":9,"t":"Kad žetvu žanjete po svojoj zemlji, ne žanjite dokraja svoje njive; niti pabirčite ostatke poslije svoje žetve."},{"v":10,"t":"Ne paljetkuj svoga vinograda; ne kupi po svom vinogradu palih boba nego ih ostavljaj sirotinji i strancu! Ja sam Jahve, Bog vaš."},{"v":11,"t":"Nemojte krasti; nemojte lagati i varati svoga bližnjega."},{"v":12,"t":"Nemojte se krivo kleti mojim imenom i tako oskvrnjivati ime svoga Boga. Ja sam Jahve!"},{"v":13,"t":"Ne iskorišćuj svoga bližnjega niti ga pljačkaj! Radnikova zarada neka ne ostane pri tebi do jutra."},{"v":14,"t":"Nemoj psovati gluhoga niti pred slijepca stavljaj zapreku. Svoga se Boga boj! Ja sam Jahve!"},{"v":15,"t":"Ne počinjajte nepravde u osudama! Ne budi pristran prema neznatnome, niti popuštaj pred velikima; po pravdi sudi svome bližnjemu!"},{"v":16,"t":"Ne raznosi klevete među svojim narodom; ne izvrgavaj pogibli krv svoga bližnjega. Ja sam Jahve!"},{"v":17,"t":"Ne mrzi svoga brata u svom srcu! Dužnost ti je koriti svoga sunarodnjaka. Tako nećeš pasti u grijeh zbog njega."},{"v":18,"t":"Ne osvećuj se! Ne gaji srdžbe prema sinovima svoga naroda. Ljubi bližnjega svoga kao samoga sebe. Ja sam Jahve!"},{"v":19,"t":"Držite moje zapovijedi! Ne daj svome blagu da se pari s drugom vrstom. Svoga polja ne zasijavaj dvjema vrstama sjemena. Ne stavljaj na se odjeće od dvije vrste tkanine."},{"v":20,"t":"Ako bi tko legao s ropkinjom koja je zaručena za drugoga, a ona ne bude ni otkupljena ni oslobođena, treba ga kazniti, ali ne smrću, jer ona nije slobodna."},{"v":21,"t":"Neka on na ulazu u Šator sastanka prinese Jahvi žrtvu naknadnicu, to jest jednoga ovna kao žrtvu naknadnicu."},{"v":22,"t":"Neka svećenik tim ovnom žrtve naknadnice izvrši nad tim čovjekom obred pomirenja pred Jahvom za počinjeni grijeh. I grijeh koji je počinio bit će mu oprošten."},{"v":23,"t":"Kad uđete u zemlju i zasadite bilo kakvu voćku, smatrajte njezine plodove za neobrezane. Tri godine neka vam budu neobrezani: neka se ne jedu."},{"v":24,"t":"Četvrte godine neka se svi njezini plodovi posvete na svetkovinu zahvale Jahvi."},{"v":25,"t":"Istom pete godine jedite njezin plod i ubirite sebi njezin urod. Ja sam Jahve, Bog vaš!"},{"v":26,"t":"Ništa s krvlju nemojte jesti! Ne gatajte! Ne čarajte!"},{"v":27,"t":"Ne zaokružujte kose na svojim sljepoočnicama; ne šišajte okrajka svoje brade."},{"v":28,"t":"Ne urezujte zareza na svome tijelu za pokojnika; niti na sebi usijecajte kakvih biljega. Ja sam Jahve!"},{"v":29,"t":"Ne obeščašćuj svoje kćeri dajući je za javnu bludnicu. Tako se zemlja neće podati bludnosti niti će se napuniti pokvarenošću."},{"v":30,"t":"Držite moje subote; štujte moje Svetište. Ja sam Jahve!"},{"v":31,"t":"Ne obraćajte se na zazivače duhova i vračare; ne pitajte ih za savjet. Oni bi vas opoganili. Ja sam Jahve, Bog vaš!"},{"v":32,"t":"Ustani pred sijedom glavom; poštuj lice starca; boj se svoga Boga. Ja sam Jahve!"},{"v":33,"t":"Ako se stranac nastani u vašoj zemlji, nemojte ga ugnjetavati."},{"v":34,"t":"Stranac koji s vama boravi neka vam bude kao sunarodnjak; ljubi ga kao sebe samoga. TÓa i vi ste bili stranci u egipatskoj zemlji. Ja sam Jahve, Bog vaš."},{"v":35,"t":"Ne počinjajte nepravde u osudama, u mjerama za duljinu, težinu i obujam."},{"v":36,"t":"Neka su vam mjerila točna; utezi jednaki; efa prava; prav hin. Ja sam Jahve, Bog vaš, koji sam vas izveo iz zemlje egipatske."},{"v":37,"t":"Držite sve moje zakone i sve moje naredbe; vršite ih. Ja sam Jahve!'”"}]},"20":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Kaži Izraelcima: 'Tko god, Izraelac, ili stranac koji živi s Izraelcima, ustupi svoje čedo Moleku, mora se smaknuti; narod zemlje neka ga kamenuje."},{"v":3,"t":"Ja ću se okrenuti protiv toga čovjeka i odstraniti ga iz njegova naroda, jer je on, ustupivši svoje čedo Moleku, okaljao moje Svetište i obeščastio moje sveto ime."},{"v":4,"t":"A ako narod zatvori svoje oči nad tim čovjekom kad svoje čedo ustupi Moleku te ga ne smakne,"},{"v":5,"t":"ja ću se suprotstaviti tome čovjeku i njegovoj obitelji; odstranit ću ih iz njihova naroda, njega i sve koji poslije njega pođu za Molekom da se podaju bludu s Molekom."},{"v":6,"t":"Ako se tko obrati na zazivače duhova i vračare da se za njima poda javnom bludu, ja ću se okrenuti protiv takva čovjeka i odstranit ću ga iz njegova naroda."},{"v":7,"t":"Posvećujte se da budete sveti! TÓa ja sam Jahve, Bog vaš."},{"v":8,"t":"Držite moje zakone i vršite ih. Ja, Jahve, posvećujem vas'.”"},{"v":9,"t":"“Tko god prokune svoga oca i svoju majku, neka se smakne. Jer je oca svoga i majku svoju prokleo, neka njegova krv padne na nj."},{"v":10,"t":"Čovjek koji počini preljub sa ženom svoga susjeda neka se kazni smrću - i preljubnik i preljubnica."},{"v":11,"t":"Čovjek koji bi legao sa ženom svoga oca - otkrio bi golotinju svoga oca - neka se oboje kazne smrću, krv njihova neka padne na njih."},{"v":12,"t":"Legne li tko sa svojom snahom, neka se oboje kazne smrću. Učinili su rodoskvrnuće i neka krv njihova padne na njih."},{"v":13,"t":"Ako bi muškarac legao s muškarcem kao što se liježe sa ženom, obojica bi počinila odvratno djelo. Neka se smaknu i krv njihova neka padne na njih."},{"v":14,"t":"Čovjek koji se oženi kćerju i njezinom majkom - krajnja je to pokvarenost! - neka se u vatri spali i on i one, da među vama ne bude pokvarenosti."},{"v":15,"t":"Čovjek koji bi spolno općio sa životinjom ima se smaknuti. Životinju ubijte!"},{"v":16,"t":"Ako bi se žena primakla bilo kakvoj životinji da se s njom pari, ubij i ženu i životinju. Neka se smaknu i njihova krv neka padne na njih."},{"v":17,"t":"Čovjek koji bi se oženio svojom sestrom, kćerju svoga oca ili kćerju svoje majke te vidio njezinu golotinju, a ona vidjela njegovu - pogrdno je to djelo! - neka se istrijebe pred očima naroda. Otkrio je golotinju svoje sestre, pa neka snosi i posljedice svoje krivnje."},{"v":18,"t":"Čovjek koji bi legao sa ženom za njezina mjesečnog pranja te otkrio njezinu golotinju - razgolio izvor njezine krvi i ona sama otkrila izvor svoje krvi - neka se oboje odstrane iz svoga naroda."},{"v":19,"t":"Ne otkrivaj golotinje sestre svoje majke niti sestre svoga oca - to je otkrivanje golotinje svoga roda, neka snose posljedice svoje krivnje."},{"v":20,"t":"Čovjek koji bi legao sa svojom strinom otkrio bi golotinju svoga strica. Neka snose posljedice svoga grijeha: neka umru bez poroda."},{"v":21,"t":"Čovjek koji bi se oženio ženom svoga brata - golotinju bi svoga brata otkrio - i to je nečisto. Neka ostanu bez poroda.”"},{"v":22,"t":"“Zato držite sve moje zakone, sve moje naredbe i vršite ih da vas ne ispljune zemlja u koju vas vodim da se u njoj nastanite."},{"v":23,"t":"Nemojte živjeti po zakonima naroda koje ja ispred vas tjeram. TÓa oni su činili sve to, i zato mi se zgadili."},{"v":24,"t":"A vama sam ja rekao: vi ćete zaposjesti njihovu zemlju; vama ću je predati u posjed - zemlju kojom teče mlijeko i med. Ja sam Jahve, vaš Bog, koji sam vas odvojio od tih naroda."},{"v":25,"t":"Pravite, dakle, razliku između čiste životinje i nečiste; između čiste ptice i nečiste. Nemojte sami sebe opoganjivati ni životinjom, ni pticom, ni bilo čim što zemljom puže: što sam vam ja odlučio kao nečisto."},{"v":26,"t":"Budite mi dakle sveti, jer sam ja, Jahve, svet; ja sam vas odvojio od tih naroda da budete moji."},{"v":27,"t":"Čovjek ili žena koji među vama postanu zazivači duhova ili vračari neka se kazne smrću; neka se kamenuju i neka njihova krv padne na njih.”"}]},"21":{"hr":[{"v":1,"t":"Jahve još reče Mojsiju: “Govori svećenicima, Aronovim sinovima, i reci im: Neka se nitko ne okalja dodirom pokojnika u svome narodu,"},{"v":2,"t":"osim svoje najbliže rodbine: svoje majke, svoga oca, svoga sina, svoje kćeri i svojega brata."},{"v":3,"t":"I svojom sestrom, djevicom, koja mu je također najbliža, jer nije bila udata, može se okaljati."},{"v":4,"t":"Ali neka se ne okalja svojom svojtom i tako se oskvrne."},{"v":5,"t":"Neka ne briju glave; neka ne šišaju okrajke svojih brada niti prave ureze na svome tijelu."},{"v":6,"t":"Neka budu posvećeni svome Bogu; neka ne oskvrnjuju ime svoga Boga, jer oni prinose žrtve u čast Jahvi paljene, hranu Boga svoga. Zato moraju biti sveti."},{"v":7,"t":"Neka se ne žene javnom bludnicom i obeščašćenom ženom; niti se smiju ženiti onom koju je njezin muž otpustio. Jer je svećenik posvećen svome Bogu."},{"v":8,"t":"Svetim ga drži, jer on prinosi hranu tvoga Boga. Neka ti je svet, jer sam svet ja, Jahve, koji vas posvećujem."},{"v":9,"t":"Ako se kći kojeg svećenika oskvrne podavši se javnom bludništvu, ona oca svoga skvrne, pa se mora na vatri spaliti.”"},{"v":10,"t":"“A svećenik koji je najveći među svojom braćom, na čiju je glavu bilo izliveno ulje pomazanja i koji je posvećen da nosi svetu odjeću, neka ne ide raščupane kose niti razdire svoje odjeće."},{"v":11,"t":"Neka ne ulazi nijednom mrtvacu; ne smije se okaljati ni za svojim ocem ni za svojom majkom."},{"v":12,"t":"Neka ne izlazi iz Svetišta, tako da ne oskvrne Svetište svoga Boga, jer na sebi nosi posvećenje uljem pomazanja Boga svoga. Ja sam Jahve!"},{"v":13,"t":"Neka za ženu uzme djevicu."},{"v":14,"t":"Udovicom, otpuštenicom, obeščašćenom i bludnicom ne smije se ženiti. Jedino djevicom između svoga naroda neka se ženi;"},{"v":15,"t":"tako neće oskvrnuti svoga potomstva među svojim narodom, jer ja, Jahve, njega posvećujem.”"},{"v":16,"t":"Jahve reče Mojsiju:"},{"v":17,"t":"“Reci Aronu: 'Nitko od tvojih potomaka, za njihovih naraštaja, koji imadne kakvu tjelesnu manu ne smije se primaknuti da prinosi hranu svoga Boga."},{"v":18,"t":"Ni jedan na kome bude mane ne smije se primaknuti: nitko koji je slijep ili sakat; nitko izobličen ili iznakažena kojeg uda;"},{"v":19,"t":"nitko tko ima slomljenu nogu ili ruku;"},{"v":20,"t":"ni poguren, ni kržljav, ni bolesnih očiju, ni lišajav, ni krastav, niti uškopljenik."},{"v":21,"t":"Dakle, ni jedan od potomaka svećenika Arona koji imadne manu neka se ne primiče da prinosi u čast Jahvi paljenu žrtvu; budući da ima manu, neka se ne primiče da prinosi hranu svoga Boga."},{"v":22,"t":"Može blagovati hranu svoga Boga i od žrtava presvetih, i svetih,"},{"v":23,"t":"ali neka ne dolazi k zavjesi niti se žrtveniku primiče jer ima manu. Neka ne skvrne mojih svetih stvari, jer sam ih ja, Jahve, posvetio.'”"},{"v":24,"t":"Mojsije to kaza Aronu, njegovim sinovima i svim Izraelcima."}]},"22":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Reci Aronu i njegovim sinovima da sveto postupaju sa svetim prinosima Izraelaca; neka ne oskvrnjuju moje sveto ime koje oni - ta moje je! - moraju svetiti. Ja sam Jahve!"},{"v":3,"t":"Reci im: 'Ako se ikad tko od vaših naraštaja primakne u stanju nečistoće k svetim prinosima što ih Izraelci posvećuju Jahvi, taj će biti uklonjen od moje nazočnosti. Ja sam Jahve!'"},{"v":4,"t":"Neka nitko od Aronovih potomaka koji bude gubav ili imadne izljev ne blaguje svetih prinosa dok ne postane čist. Onaj koji se dotakne bilo čega što je mrtvo tijelo okaljalo ili onaj koji iz sebe prospe sjemeni izljev;"},{"v":5,"t":"onaj koji se dotakne kakva puzavca koji ga onečisti; ili čovjeka od kojega se okalja bilo kakvom nečistoćom -"},{"v":6,"t":"onaj koji se dotakne čega takva neka je nečist do večeri i neka ne blaguje svetih prinosa dok ne okupa svoje tijelo u vodi."},{"v":7,"t":"Čim sunce zađe, čist je. Poslije toga može blagovati od svetih prinosa jer mu je to hrana."},{"v":8,"t":"Neka ne jede ni strva ni što je zvjerad rastrgla. Time bi se okaljao."},{"v":9,"t":"Neka drže moje naredbe, da ne navuku na se krivnju i zbog nje, oskvrnuvši se, ne poginu. Ta ja, Jahve, njih posvećujem.”"},{"v":10,"t":"“Neka nijedan svjetovnjak ne blaguje od prinosa; ni ukućanin ni svećenikov sluga ne smije jesti od svetoga prinosa."},{"v":11,"t":"Ali ako svećenik steče koga novcem u svoje vlasništvo, taj to može jesti kao onaj što se rodi u njegovoj kući; oni mogu jesti od njegove hrane."},{"v":12,"t":"Ako se svećenikova kći uda za svjetovnjaka, ne smije blagovati od podizanih svetih prinosa."},{"v":13,"t":"Ali ako svećenikova kći obudovi ili bude otpuštena, a nema djece pa se vrati u očevu kuću, može se hraniti očevom hranom kao u svojoj mladosti. Nikakav svjetovnjak ne smije što od toga jesti."},{"v":14,"t":"Bude li tko iz neznanja jeo sveti prinos, neka ga nadoknadi svećeniku dodajući petinu."},{"v":15,"t":"Neka ne oskvrnjuju svetih prinosa što ih Izraelci Jahvi podižu."},{"v":16,"t":"Jedući ih, navukli bi na se krivnju koja bi ih obvezivala na nadoknadu, jer ja, Jahve, posvetio sam te prinose.”"},{"v":17,"t":"Jahve reče Mojsiju:"},{"v":18,"t":"“Govori Aronu, njegovim sinovima i svim Izraelcima i reci im: 'Svaki čovjek doma Izraelova ili stranac u Izraelu koji donosi svoj prinos kao zavjet ili kao dragovoljan dar da se prinese Jahvi kao žrtva paljenica - da bude primljen -"},{"v":19,"t":"mora prinijeti muško bez mane, bilo to goveče, ovca ili koza."},{"v":20,"t":"Nikakvo s manom na njemu nemojte prinositi jer vam to neće biti primljeno."},{"v":21,"t":"Ako tko prinosi Jahvi žrtvu pričesnicu da izvrši kakav zavjet ili učini dragovoljan prinos, bilo od krupne ili sitne stoke, ta životinja, da bude primljena, mora biti bez mane; nikakve mane na njoj ne smije biti."},{"v":22,"t":"Nikakvu slijepu, ili hromu, ili osakaćenu, gušavu, šugavu ili krastavu životinju, nikakvu takvu Jahvi nemoj prinositi niti ikakvu takvu na žrtvenik kao paljenu žrtvu Jahvi polagati."},{"v":23,"t":"Junca ili ovcu s kakvim udom protegnutim ili prikaćenim možeš prinijeti kao dragovoljan prinos, ali kao žrtva zavjetnica neće biti primljena."},{"v":24,"t":"Jahvi nemojte prinositi životinje sa zgnječenim, stučenim, rastrgnutim ili odsječenim mošnjama. To u svoj zemlji ne činite"},{"v":25,"t":"niti takvo što primajte od stranca da to prinesete kao hranu svoga Boga. S manom su jer su osakaćene. Zato vam neće biti primljene.'”"},{"v":26,"t":"Jahve reče Mojsiju:"},{"v":27,"t":"“Kad se tele oteli, janje se ojanji ili se kozle okozi, sedam dana neka ostane uza svoju majku. Od osmoga dana može biti primljeno kao paljena žrtva Jahvi."},{"v":28,"t":"Ne koljite krave ni ovce u isti dan s njezinim mladim."},{"v":29,"t":"Kad Jahvi žrtvujete žrtvu zahvalnicu, žrtvujte je tako da budete primljeni."},{"v":30,"t":"Neka se žrtva blaguje onoga istog dana; od nje ništa ne ostavljajte za ujutro. Ja sam Jahve!”"},{"v":31,"t":"“Moje zapovijedi držite i vršite ih. Ja sam Jahve!"},{"v":32,"t":"Ne oskvrnjujte moga svetog imena, nego neka budem proglašen svetim među Izraelcima - ja, Jahve, koji vas posvećujem."},{"v":33,"t":"Ja koji sam vas izbavio iz zemlje egipatske da budem vaš Bog, ja, Jahve.”"}]},"23":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Kaži Izraelcima i reci im: Blagdani Jahvini koje imate sazivati jesu sveti zborovi. Ovo su moji blagdani:"},{"v":3,"t":"Šest dana neka se posao obavlja, a sedmi je dan subota - dan potpunog odmora, dan svetoga zbora, kad ne smijete raditi nikakva posla. Gdje god boravili, subota je Jahvina.”"},{"v":4,"t":"“A ovo su blagdani Jahvini - sveti zborovi - koje imate proglasiti u njihovo određeno vrijeme:"},{"v":5,"t":"U prvom mjesecu četrnaestoga dana u suton jest Pasha u čast Jahvi;"},{"v":6,"t":"petnaestoga dana toga mjeseca jest Blagdan beskvasnih kruhova u čast Jahvi - sedam dana jedite beskvasan kruh."},{"v":7,"t":"Prvoga dana neka vam bude sveti zbor; nikakva težačkog posla nemojte raditi."},{"v":8,"t":"Sedam dana prinosite paljenu žrtvu u čast Jahvi, a sedmoga dana neka opet bude sveti zbor; nikakva težačkog posla ne radite.”"},{"v":9,"t":"Jahve reče Mojsiju:"},{"v":10,"t":"“Kaži Izraelcima i reci im: 'Kad uđete u zemlju koju vam dajem i u njoj žetvu požanjete, prvi snop svoje žetve donesite svećeniku."},{"v":11,"t":"Neka ga on prinese kao žrtvu prikaznicu pred Jahvom da budete primljeni. Sutradan po suboti neka ga svećenik prinese kao žrtvu prikaznicu."},{"v":12,"t":"A u dan kad budete prinosili snop kao žrtvu prikaznicu, prinesite Jahvi jednogodišnjeg janjca bez mane kao žrtvu paljenicu."},{"v":13,"t":"Uz to žrtva prinosnica neka bude: dvije desetine efe najboljeg brašna zamiješena u ulju, kao paljena žrtva Jahvi na ugodan miris; a s njom ljevanica od vina neka bude četvrt hina."},{"v":14,"t":"Prije toga dana - dok ne donesete prinose svoga Boga - ne smijete jesti ni kruha, ni pržena zrnja, ni svježa klasja. To je trajan zakon za vaše naraštaje gdje god vi boravili.'”"},{"v":15,"t":"“A počevši od sutrašnjega dana po suboti - dana u koji donesete snop za žrtvu prikaznicu - nabrojte punih sedam tjedana."},{"v":16,"t":"Onda na dan po sedmoj suboti, na Pedesetnicu, prinesite Jahvi novu žrtvu."},{"v":17,"t":"Donesite iz svojih stanova po dva kruha za žrtvu prikaznicu. Neka svaki bude od dvije desetine efe najboljeg brašna; neka budu ispečeni ukvas, kao prvine Jahvi."},{"v":18,"t":"S kruhom prinesite sedam jednogodišnjih janjaca bez mane, jednoga junca i dva ovna kao žrtvu paljenicu Jahvi zajedno sa žrtvom prinosnicom i ljevanicom, žrtvom paljenom na ugodan miris Jahvi."},{"v":19,"t":"Prinesite i jednoga jarca kao žrtvu okajnicu, a dva janjca od godine dana za žrtvu pričesnicu."},{"v":20,"t":"Neka ih svećenik prinese pred Jahvom kao žrtvu prikaznicu povrh kruha od prvina. Uz oba janjca, i ovo je Jahvi sveto i neka pripadne svećeniku."},{"v":21,"t":"Toga istog dana sazovite zbor. Neka vam to bude posvećen zbor - nikakva težačkog posla ne radite. To je trajan zakon za vaše naraštaje gdje god vi boravili."},{"v":22,"t":"Kad budete želi žetvu sa svoje zemlje, nemoj žeti dokraja svoje njive niti pabirčiti poslije svoje žetve. Ostavi to sirotinji i strancu. Ja sam Jahve, Bog vaš.”"},{"v":23,"t":"Jahve reče Mojsiju:"},{"v":24,"t":"“Govori Izraelcima i reci: 'Sedmoga mjeseca, prvoga dana u mjesecu, neka vam je potpun odmor, proglašen glasom trube, sveti zbor."},{"v":25,"t":"Nikakva teškog posla ne radite; u čast Jahvi paljenu žrtvu prinesite.'”"},{"v":26,"t":"Reče Jahve Mojsiju:"},{"v":27,"t":"“Povrh toga, u deseti dan toga sedmog mjeseca pada Dan pomirenja. Neka vam to bude prigoda za sveti zbor; postite i prinesite u čast Jahvi paljenu žrtvu."},{"v":28,"t":"Toga dana nemojte raditi nikakva posla. To je, naime, Dan pomirenja, kada će se za vas obaviti obred pomirenja pred Jahvom, Bogom vašim."},{"v":29,"t":"Jest, tko god ne bude postio toga dana, neka se odstrani iz svoga naroda."},{"v":30,"t":"A tko bi god radio kakav posao na taj dan, toga ću ja istrijebiti iz njegova naroda."},{"v":31,"t":"Nikakva posla nemojte raditi. To je trajan zakon za vaše naraštaje gdje god vi boravili."},{"v":32,"t":"Neka vam je to subotnji počinak. Postite! Navečer devetoga dana u mjesecu - od večeri do večeri - prestanite raditi.”"},{"v":33,"t":"Jahve reče Mojsiju:"},{"v":34,"t":"“Reci Izraelcima: 'Od petnaestoga dana toga sedmog mjeseca neka se sedam dana drži Blagdan sjenica u čast Jahvi."},{"v":35,"t":"Prvoga dana, u dan svetoga zbora, nikakva težačkog posla nemojte raditi."},{"v":36,"t":"Sedam dana prinosite paljenu žrtvu u čast Jahvi. Osmi dan neka vam bude sveti zbor, kada ćete u čast Jahvi prinijeti paljenu žrtvu. To je svečani zbor; nikakva težačkog posla nemojte obavljati.'”"},{"v":37,"t":"“To su blagdani Jahvini koje imate sazvati - sveti zborovi određeni za prinošenje žrtava u čast Jahvi; žrtava paljenica, prinosnica, žrtava klanica i ljevanica; svaku na njezin pravi dan,"},{"v":38,"t":"povrh Jahvinih subota, povrh vlastitih prinosa, povrh svojih zavjetnih i dragovoljnih darova koje inače prinosite Jahvi.”"},{"v":39,"t":"“Osim toga, petnaestoga dana mjeseca sedmoga, pošto pokupite sa zemlje plodove, svetkujte Jahvin blagdan sedam dana. Na prvi dan i na osmi dan neka je potpun počinak."},{"v":40,"t":"Uzmite već prvoga dana lijepih plodova, palmovih grana, grančica s lisnatih drveta i potočne vrbovine pa se veselite u nazočnosti Jahve, Boga svoga, sedam dana."},{"v":41,"t":"Svetkujte tako blagdan u čast Jahvi sedam dana svake godine. Neka je to trajan zakon za vaše naraštaje. Svetkujte taj blagdan sedmoga mjeseca."},{"v":42,"t":"Sedam dana stanujte u sjenicama. Svi Izraelovi domoroci neka proborave u sjenicama,"},{"v":43,"t":"da vaši potomci znaju kako sam ja učinio da Izraelci žive u sjenicama kad sam ih izbavio iz zemlje egipatske. Ja sam Jahve, Bog vaš.”"},{"v":44,"t":"I tako Mojsije objavi Izraelcima Jahvine blagdane."}]},"24":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Naredi Izraelcima da ti za svijećnjak donose čistoga ulja od istupanih maslina, da se uvijek održava svjetlo."},{"v":3,"t":"Neka ga Aron svagda sprema pred Jahvom od večeri do jutra u Šatoru sastanka, pred zavjesom Svjedočanstva. Neka je ovo trajan zakon vašim naraštajima."},{"v":4,"t":"Neka Aron neprekidno održava svjetlila na čistome svijećnjaku pred Jahvom.”"},{"v":5,"t":"“Potom uzmi najboljeg brašna i od njega ispeci dvanaest pogača. Neka u svakoj pogači budu dvije desetine efe."},{"v":6,"t":"Onda ih poredaj u dva reda - po šest u redu - na čistome stolu što je pred Jahvom."},{"v":7,"t":"Na svaki red stavi čistoga tamjana. Neka to bude hrana prinesena kao spomen - paljena žrtva Jahvi."},{"v":8,"t":"Svake subote, bez prijekida, neka se postavljaju pred Jahvu. To neka Izraelci vrše zbog vječnoga Saveza."},{"v":9,"t":"Neka pripadnu Aronu i njegovim sinovima. Oni ih imaju blagovati na posvećenu mjestu. To je njemu vrlo svet dio Jahvinih paljenih žrtava. To neka bude trajna odredba.”"},{"v":10,"t":"A sin jedne Izraelke, komu otac bijaše Egipćanin, iziđe među Izraelce i zametne u taboru svađu s nekim Izraelcem."},{"v":11,"t":"Uto sin Izraelke pogrdi Ime i opsuje ga. Tada ga dovedu Mojsiju. - Mati mu se zvala Šelomit, a bila je kći Dibrijeva iz plemena Danova. -"},{"v":12,"t":"Stave ga u zatvor dok im se ne očituje volja Jahvina."},{"v":13,"t":"Onda Jahve reče Mojsiju:"},{"v":14,"t":"“Izvedi psovača iz tabora. Potom svi oni koji su ga čuli neka stave svoje ruke na njegovu glavu. A onda neka ga sva zajednica kamenuje."},{"v":15,"t":"Poslije toga ćeš ovako prozboriti Izraelcima: Tko god opsuje Boga svoga neka snosi svoju krivnju;"},{"v":16,"t":"tko izgovori hulu na ime Jahvino neka se smakne - neka ga sva zajednica kamenuje; bio stranac ili domorodac, ako pohuli ime Jahvino, mora mrijeti."},{"v":17,"t":"Ako čovjek zada smrtan udarac drugome, mora se smaknuti."},{"v":18,"t":"Tko usmrti živinče mora ga nadomjestiti: život za život."},{"v":19,"t":"Tko ozlijedi svoga bližnjega neka mu se učini kako je on učinio:"},{"v":20,"t":"lom za lom, oko za oko, zub za zub - rana koju je on zadao drugome neka se zada i njemu."},{"v":21,"t":"Tko usmrti živinče mora ga nadoknaditi, ali tko ubije čovjeka mora umrijeti."},{"v":22,"t":"Neka vam je jednak sud i strancu i domorocu. Jer ja sam Jahve, Bog vaš.”"},{"v":23,"t":"Pošto je Mojsije to izložio Izraelcima, oni izvedu psovača izvan tabora i zaspu ga kamenjem. Učine, dakle, Izraelci kako je Jahve Mojsiju naredio."}]},"25":{"hr":[{"v":1,"t":"Jahve reče Mojsiju na Sinajskom brdu:"},{"v":2,"t":"“Govori Izraelcima i kaži im: Kad uđete u zemlju koju vam dajem, neka ta zemlja održava Jahvin subotni počinak."},{"v":3,"t":"Šest godina zasijavaj svoju njivu, šest godina svoj vinograd obrezuj i beri njegov plod."},{"v":4,"t":"Ali sedme godine neka i zemlja uživa subotnji počinak, Jahvinu subotu: svoje njive ne zasijavaj niti obrezuj svoga vinograda."},{"v":5,"t":"Što samo od sebe uzraste na tvojoj njivi nemoj žeti niti beri grožđe s neobrezane loze. Neka to bude zemlji godina počivanja."},{"v":6,"t":"Zemljišni počinak neka vam priskrbi prehranu: tebi, tvome sluzi, tvojoj sluškinji, tvome najamniku koji s tobom živi;"},{"v":7,"t":"a i tvojoj stoci i zvjeradi u tvojoj zemlji neka njezini plodovi služe za hranu.”"},{"v":8,"t":"“Nabroj sedam sedmica takvih godina, sedam puta sedam godina. Sedam sedmica godina iznosit će ti četrdeset devet godina."},{"v":9,"t":"A onda zaori u trubu! U sedmome mjesecu, desetoga dana toga mjeseca, na Dan pomirenja, zatrubite u trubu širom svoje zemlje."},{"v":10,"t":"Tu pedesetu godinu proglasite svetom! Zemljom proglasite oslobađanje svim njezinim stanovnicima. To neka vam bude jubilej, oprosna godina. Neka se svatko vaš vrati na svoju očevinu; neka se svatko vrati k svome rodu!"},{"v":11,"t":"Ta pedesetogodišnjica neka vam je jubilejska godina: nemojte sijati, nemojte žeti što samo od sebe uzraste niti berite grožđe s neobrezane loze."},{"v":12,"t":"Jer jubilej vam mora biti svet! Hranite se onim što njiva donese od sebe."},{"v":13,"t":"Te jubilejske godine neka se svatko vrati na svoju očevinu."},{"v":14,"t":"Zato, kad prodajete imanje svome sunarodnjaku ili kupujete od svoga sunarodnjaka, nemojte nanositi štete svome bratu!"},{"v":15,"t":"Od svoga sunarodnjaka kupuj, odbivši samo broj godina poslije jubileja, a on neka ti proda prema broju proizvodnih godina."},{"v":16,"t":"Što više godina, više i cijenu povisi; što manje godina, neka je i cijena manja. Jer, ono što ti on prodaje jest broj ljetina."},{"v":17,"t":"Neka nitko od vas ne nanosi štete svome sunarodnjaku, nego se boj Boga svoga! Jer ja sam Jahve, Bog vaš."},{"v":18,"t":"Vršite moje zakone i moje naredbe; vjerno ih provodite u djelo pa ćete u sigurnosti živjeti na zemlji."},{"v":19,"t":"Zemlja će davati svoj rod, jest ćete do sitosti i živjet ćete u sigurnosti."},{"v":20,"t":"Ako biste rekli: 'Čime ćemo se hraniti te sedme godine kad ne budemo ni sijali ni brali plodova?'"},{"v":21,"t":"evo, blagoslov ću svoj pustiti na vas: šesta godina rodom će roditi za tri godine."},{"v":22,"t":"Kad budete sijali osme godine, hranit ćete se starim prihodom sve do devete godine; dok ne dođe njezin prihod, jest ćete stari.”"},{"v":23,"t":"“Zemlja se ne smije prodati potpuno, jer zemlja pripada meni, dok ste vi samo stranci i gosti kod mene."},{"v":24,"t":"Zato u svakome kraju gdje imate zemljišne posjede morate dopustiti otkupljivanje zemlje."},{"v":25,"t":"Ako tvoj brat zapadne u škripac te moradne prodati dio svoje očevine, neka dođe njegov najbliži izbavitelj i otkupi što je njegov brat prodao."},{"v":26,"t":"Ako nema koga da mu ga otkupi, a poslije i sam postane imućan te stekne sredstva da je otkupi,"},{"v":27,"t":"neka prebroji godine od prodaje, isplati kupcu svotu za preostalo vrijeme i vrati se na svoju očevinu."},{"v":28,"t":"Ako nema sredstava da je vrati, onda prodano neka ostane u rukama kupca do jubilejske godine. A stupivši u jubilej, neka se vrati na svoju očevinu."},{"v":29,"t":"Ako tko proda stojnu kuću u gradu zidom obzidanu, može je otkupiti dokle se ne navrši godina poslije prodaje; otkupni rok neka je, dakle, jedna godina."},{"v":30,"t":"Ako je ne otkupi u roku od godine, onda kuća u gradu zidom opasana prelazi potpuno kupcu i njegovim potomcima: ni za jubileja neka se ne vraća."},{"v":31,"t":"Ali kuće po selima što nemaju zidova oko sebe neka se smatraju kao posjedi u polju; mogu se otkupljivati. U jubileju kupac mora iz njih izići."},{"v":32,"t":"Kuće koje u levitskim gradovima pripadaju levitima mogu leviti otkupiti u svako vrijeme."},{"v":33,"t":"Ako se koji levit ne posluži svojim pravom otkupa, onda će kuća što bude prodana u gradu njegova vlasništva biti za jubileja vraćena. Jer kod Izraelaca kuće u gradovima levita njihovo su vlasništvo."},{"v":34,"t":"Neograđena zemlja oko njihovih gradova ne može se prodati, jer je ona njihovo vlasništvo za sva vremena.”"},{"v":35,"t":"“Ako tvoj brat zapadne u škripac i ne mogne održavati svoje odnose s tobom, primi ga; i neka s tobom živi kao stranac ili gost."},{"v":36,"t":"Ne uzimaj od njega ni lihve ni kamata. Boga se svoga boj, i neka tvoj brat živi s tobom!"},{"v":37,"t":"Ne uzajmljuj mu novac na kamate niti mu lihvarski davaj svoju hranu."},{"v":38,"t":"Ja, Jahve, Bog vaš, izbavio sam vas iz zemlje egipatske da vam dadem zemlju kanaansku i budem vaš Bog."},{"v":39,"t":"Ako li tvoj brat padne u škripac dok je s tobom u urednim odnosima te se moradne tebi prodati, nemoj ga prisiliti da služi kao rob; neka bude kod tebe kao najamnik ili nadničar."},{"v":40,"t":"Neka služi kod tebe do jubilejske godine."},{"v":41,"t":"Onda neka bude slobodan da ode od tebe - i on i njegova djeca s njim; neka ide natrag svome rodu i opet zaposjedne svoju djedovinu."},{"v":42,"t":"TÓa oni su moji službenici, ja sam ih izbavio iz zemlje egipatske; oni se ne smiju prodavati kao robovi."},{"v":43,"t":"Nemoj s njim grubo postupati! Boga se svoga boj!"},{"v":44,"t":"A robove i ropkinje, budeš li ih htio imati, možete kupiti, i muške i ženske, od naroda koji su oko vas."},{"v":45,"t":"Možete ih kupovati i od pridošlica koji s vama borave; od njihovih obitelji što žive s vama i rođeni su u vašoj zemlji. Takvi mogu postati vašim vlasništvom."},{"v":46,"t":"Njih možete predati u nasljedstvo svojoj djeci da ih zavazda naslijede u baštinu. Prema njima možete postupati kao prema robovima. Ali prema svojoj braći, Izraelcima, nitko ne smije grubo postupati."},{"v":47,"t":"Ako se stranac s tobom nastanjen obogati, a tvoj brat, u svojim odnosima prema njemu, zapadne u škripac te se proda strancu koji je s tobom nastanjen ili kojemu god potomku strančeve obitelji,"},{"v":48,"t":"on ima pravo i nakon prodaje biti otkupljen. Neka ga otkupi netko od njegove braće;"},{"v":49,"t":"ili neka ga otkupi njegov stric, njegov rođak ili bilo tko od njegove obitelji koji bude od njegove krvi. Ili, ako ima sredstava, neka se sam otkupi."},{"v":50,"t":"Sa svojim kupcem neka proračuna vrijeme od godine kad mu se prodao do jubilejske godine. Cijena za njegovo oslobođenje neka bude prema broju godina. Vrijeme što ga je proveo sa svojim vlasnikom neka se procijeni kao vrijeme jednog najamnika."},{"v":51,"t":"Ako ostaje još mnogo godina, neka isplati za svoju otkupninu u omjeru svoje prodajne svote."},{"v":52,"t":"A ako ostaje samo nekoliko godina do jubilejske godine, neka izračuna pa isplati za svoj otkup prema godinama službe."},{"v":53,"t":"Prema njemu neka bude kao prema najamniku koji se iznajmljuje od godine na godinu. Neka se na tvoje oči s njim ne postupa grubo."},{"v":54,"t":"Ne bude li iskupljen ovako, onda i on i njegova djeca s njim neka odu u jubilejskoj godini."},{"v":55,"t":"Jer Izraelci su moji službenici; oni su moji službenici koje sam ja izveo iz zemlje egipatske, ja, Jahve, Bog vaš.”"}]},"26":{"hr":[{"v":1,"t":"“Ne pravite sebi kumira; ne podižite sebi ni kipa ni spomen-stupa; ne postavljajte u svojoj zemlji kamenja s likovima da pred njih padate."},{"v":2,"t":"Održavajte moje subote; poštujte moje Svetište - jer ja sam Jahve, Bog vaš.”"},{"v":3,"t":"“Budete li živjeli prema mojim zakonima, održavali moje zapovijedi i u djelo ih provodili,"},{"v":4,"t":"davat ću vam kiše u pravo vrijeme te će zemlja rađati rodom a stabla po polju donositi plodove."},{"v":5,"t":"Vršidba će vam stizati berbu, a berba stizati sjetvu. Jest ćete kruh svoj do sitosti i u svojoj ćete zemlji živjeti u sigurnosti."},{"v":6,"t":"Zemlji ću dati mir; tako ćete počivati a da vas nitko ne plaši. Štetne ću životinje iz zemlje ukloniti; mač neće prolaziti vašom zemljom."},{"v":7,"t":"U bijeg ćete nagoniti svoje neprijatelje, a oni će padati pred vama od mača."},{"v":8,"t":"Petorica vas nagonit će u bijeg stotinu njih, a stotina vas nagonit će u bijeg deset tisuća njih. Da, vaši će neprijatelji padati pred vama od mača."},{"v":9,"t":"K vama ću se okrenuti te vas rodnima činiti i razmnažati. Držat ću svoj Savez s vama."},{"v":10,"t":"Starom ćete se zalihom hraniti; štoviše, trebat će vam zalihe ispražnjavati da mognete sasipati novo žito."},{"v":11,"t":"Među vama ću postaviti svoje Prebivalište i neću vas odbaciti;"},{"v":12,"t":"među vama ću hoditi i bit ću vam Bog, a vi ćete mi biti narod."},{"v":13,"t":"Ja, Jahve, Bog vaš, izveo sam vas iz zemlje egipatske da im više ne budete roblje; polomio sam palice vaših jarmova i učinio da hodate uspravno.”"},{"v":14,"t":"“Ali ako me ne poslušate i u djelo ne provedete sve ove moje zapovijedi;"},{"v":15,"t":"ako odbacite moje zakone, pogazite moje naredbe i prekršite moj Savez, ne provodeći u djelo sve moje zapovijedi,"},{"v":16,"t":"evo što ću ja učiniti vama: podvrgnut ću vas strepnji, iznemoglosti i groznici što oči troše a život gase."},{"v":17,"t":"Sjetve ćete svoje uzalud sijati - neprijatelji vaši njima će se hraniti. Ja ću se protiv vas okrenuti, a vaši će vas neprijatelji ametice tući. Oni koji vas mrze gospodarit će nad vama. Bježat ćete i onda kad vas nitko ne bude progonio."},{"v":18,"t":"Pa ako me i unatoč tome ne poslušate, ja ću vas sedmerostruko kažnjavati za vaše grijehe."},{"v":19,"t":"Slomit ću ja vašu drsku silu. Vaša ću nebesa učiniti poput gvožđa, a zemlju vašu poput tuča."},{"v":20,"t":"Uzalud će se trošiti vaša snaga. Zemlja vam više neće davati svoga roda niti će stabla na zemlji donositi svojih plodova."},{"v":21,"t":"Budete li se još i dalje protivili, ne htjednete li me poslušati, sedmerostruko ću još na vama povisiti rane za vaše grijehe."},{"v":22,"t":"Na vas ću pustiti šumsku zvjerad da vas liši djece, blago vam podavi a vas prorijedi tako da vam putovi postanu pusti."},{"v":23,"t":"Ako vas ni to ne popravi nego nastavite življenje koje se meni protivi,"},{"v":24,"t":"onda ću se i ja suprotstaviti vama i sam ću vas još sedmerostruko udariti za vaše grijehe."},{"v":25,"t":"Na vas ću dovesti mač neka se iskali osvetom za Savez. A kad se zbijete u svoje gradove, poslat ću na vas kugu i bit ćete predani u ruke neprijatelju."},{"v":26,"t":"Još kad vam obustavim namicanje kruha, deset žena moći će vam peći kruh u jednoj peći i na mjeru će vam kruh davati. Jest ćete, ali se nećete nasititi."},{"v":27,"t":"Ako me ni tada ne poslušate nego mi se dalje budete suprotstavljali,"},{"v":28,"t":"i ja ću se vama suprotstaviti - sedmerostruko ću vas kazniti za vaše grijehe."},{"v":29,"t":"Jest ćete meso od svojih sinova, jest ćete meso od svojih kćeri."},{"v":30,"t":"Porušit ću vaše idolske uzvišice; oborit ću vaše kadione žrtvenike, zgrnut ću vaša mrtva trupla na trupla vaših kumira i odbacit ću vas."},{"v":31,"t":"Gradove ću vaše pretvoriti u ruševine; svetišta ću vaša opustošiti, vaš ugodni miris neću više mirisati."},{"v":32,"t":"Zemlju ću ja pretvoriti u zgarište tako da će se vaši neprijatelji koji se u njoj nastane zaprepastiti nad njom."},{"v":33,"t":"Vas ću rasijati po narodima; izvući ću protiv vas mač iz korica tako da će vam se zemlja pretvoriti u pustaru a gradovi u ruševine."},{"v":34,"t":"Tada će zemlja namiriti svoje subote za sve vrijeme dok bude pusta i vi budete u zemlji svojih neprijatelja. Otpočinut će tada zemlja i moći će namiriti svoje subote."},{"v":35,"t":"Sve dok bude pusta, imat će počinak koji nije imala za vaših subota dok ste vi u njoj stanovali."},{"v":36,"t":"A onima od vas koji na životu ostanu po zemljama svojih neprijatelja, njima ću strah u srce utjerati. U bijeg će ih nagoniti šuštaj lista što zatrepti. Bježat će kao što se bježi od mača; padat će, iako ih nitko neće progoniti."},{"v":37,"t":"Spoticat će se jedan o drugoga kao kad se bježi ispred mača, premda ih nitko neće progoniti. Nećete se održati pred svojim neprijateljima;"},{"v":38,"t":"izginut ćete među narodima - proždrijet će vas zemlja vaših neprijatelja."},{"v":39,"t":"A koji od vas prežive venut će u zemljama svojih neprijatelja zbog svojih opačina; venut će i zbog opačina svojih otaca."},{"v":40,"t":"Priznat će tada svoju opačinu i opačinu svojih otaca što su je protiv mene počinili izdajom, što su mi se protivili."},{"v":41,"t":"I ja sam sa morao suprotstaviti njima i odvesti ih u zemlju njihovih neprijatelja.” “Onda će se napokon njihovo tvrdokorno srce poniziti; ispaštat će oni svoju krivnju."},{"v":42,"t":"Tada ću se ja sjetiti svoga Saveza s Jakovom i svoga Saveza s Izakom; sjetit ću se svoga Saveza s Abrahamom - zemlje ću se sjetiti."},{"v":43,"t":"Zemlja će, ostavljena od njih, namiriti svoje subote kad ostane pusta zbog njih. A oni će ispaštati svoju krivnju što su odbacili moje zapovijedi; što su prezreli moje zakone."},{"v":44,"t":"Ali ni onda dok budu u zemlji svojih neprijatelja, neću ih zabaciti niti ću ih prezreti tako da ih posve uništim i da prekršim svoj Savez s njima. TÓa ja sam Jahve, Bog njihov."},{"v":45,"t":"Radi njih sjetit ću se Saveza s njihovim precima koje sam izveo iz zemlje egipatske naočigled naroda da budem njihov Bog, ja Jahve.”"},{"v":46,"t":"To su odredbe, uredbe i zakoni koje je Jahve uglavio između sebe i Izraelaca po Mojsiju na Sinajskome brdu."}]},"27":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Govori Izraelcima i reci im: 'Ako tko zaželi podmiriti Jahvi zavjet što vrijedi koliko čovjek,"},{"v":3,"t":"neka ti je mjerilo: muškarca od dvadeset do šezdeset godina starosti procijeni pedeset šekela u srebru, prema hramskom šekelu,"},{"v":4,"t":"a žensku procijeni trideset šekela."},{"v":5,"t":"A za dob od pet do dvadeset godina neka tvoja procjena bude: za muškarca dvadeset šekela, a za žensku deset šekela."},{"v":6,"t":"Je li dob od jednoga mjeseca do pet godina, neka ti je procjena: za muško pet šekela u srebru, a procjena za žensko tri šekela u srebru."},{"v":7,"t":"Bude li u starosti od šezdeset godina ili više, neka ti je procjena: za muškarca petnaest šekela, a za žensku deset šekela."},{"v":8,"t":"Ali ako je tko siromašan te ne može platiti svoju cijenu, neka ga dovedu pred svećenika i neka ga svećenik procijeni. Ali neka svećenik procijeni prema onome što zavjetovalac može dati."},{"v":9,"t":"Ako zavjetovani prinos bude od životinja koje se mogu Jahvi prinositi, svaki takav prinos Jahvi bit će posvećena stvar."},{"v":10,"t":"Neka se ne nadomješta niti zamjenjuje za što drugo - bilo dobro za loše, bilo loše za dobro. Ako li se napravi zamjena jednoga živinčeta za drugo, onda će i zavjetovano i ono koje ga je zamijenilo biti posvećena stvar."},{"v":11,"t":"Bude li zavjetovani prinos od nečiste životinje koja se ne može Jahvi prinositi, neka se takvo živinče dovede k svećeniku"},{"v":12,"t":"pa neka ga on procijeni. Bilo skupo, bilo jeftino, kako svećenik procijeni, neka tako bude."},{"v":13,"t":"Zaželi li ga tko otkupiti, neka doda njegovoj procjeni jednu petinu."},{"v":14,"t":"Ako tko posveti svoju kuću zavjetovavši je Jahvi, neka svećenik procijeni da li je dobra ili loša. Kako svećenik prosudi, neka tako ostane."},{"v":15,"t":"Ako onaj koji je svoju kuću zavjetovao zaželi da je otkupi, neka dometne jednu petinu svoti na koju je procijenjena pa neka bude njegova."},{"v":16,"t":"Ako tko zavjetuje Jahvi dio zemljišta od svoga vlasništva, procijeni ga prema njegovu usjevu: za jedan homer ječmena sjemena pedeset šekela u srebru."},{"v":17,"t":"Zavjetuje li zemljište za jubilejske godine, neka ostane prema ovoj procjeni."},{"v":18,"t":"Ali ako zemljište zavjetuje poslije jubilejske godine, neka svećenik proračuna cijenu prema godinama što preostaju do jubilejske godine i prema tome smanji procjenu."},{"v":19,"t":"Ako onaj tko je zemljište zavjetovao zaželi da ga otkupi, neka doda jednu petinu svoti na koju je procijenjeno pa neka mu ostane."},{"v":20,"t":"Ako zemljište ne otkupi nego ga proda drugome, ne može se više otkupiti."},{"v":21,"t":"Kad zemljište bude oslobođeno u jubilejskoj godini, neka se posveti Jahvi kao zavjetovano zemljište i postane svećenikov posjed."},{"v":22,"t":"Zavjetuje li tko Jahvi kupljeno zemljište koje nije dio njegove očevine,"},{"v":23,"t":"neka mu svećenik proračuna razmjernu procjenu do jubilejske godine. I toga istog dana neka isplati iznos kao stvar posvećenu Jahvi."},{"v":24,"t":"U jubilejskoj godini zemljište se ima vratiti onome od koga je kupljeno - kome pripada zemljišno vlasništvo."},{"v":25,"t":"Svaka procjena neka se vrši prema hramskom šekelu: dvadeset gera jedan šekel."},{"v":26,"t":"Ali neka nitko ne zavjetuje prvinu od stoke. TÓa prvina ionako pripada Jahvi - Jahvina je, pa bila od sitnoga bila od krupnoga blaga."},{"v":27,"t":"Bude li od nečiste stoke, može se otkupiti prema procjeni, dometnuvši petinu cijene. Ako se ne otkupi, neka se prema procjeni proda."},{"v":28,"t":"Ali ništa od 'herema', od onog što je Jahvi izručeno, bio to čovjek ili živinče ili njegovo baštinjeno zemljište, ništa što je tko Jahvi zavjetom posvetio, ne može se niti prodati niti otkupiti. Svaka zavjetom posvećena stvar najveća je Jahvina svetinja."},{"v":29,"t":"Nijedno ljudsko biće koje bude 'heremom' - prokletstvom - udareno ne smije se otkupljivati: mora se smaknuti."},{"v":30,"t":"Svaka desetina sa zemljišta, bilo od poljskih usjeva bilo od plodova sa stabala, pripada Jahvi; to je Jahvi posvećeno."},{"v":31,"t":"Ako bi tko htio otkupiti koji dio svoje desetine, mora tome dodati jednu petinu cijene."},{"v":32,"t":"Svaka desetina od krupnoga i sitnoga blaga, to jest svako deseto od svega što prolazi ispod pastirskog štapa, neka bude posvećeno Jahvi."},{"v":33,"t":"Neka se ne gleda je li dobro ili rđavo; i neka se ne zamjenjuje. Ako se ipak zamijeni, neka je onda i jedno i drugo posvećeno i ne smije se otkupljivati.'”"},{"v":34,"t":"To su zapovijedi koje je Jahve izdao Mojsiju za Izraelce na Sinajskome brdu."}]}},"NUM":{"1":{"hr":[{"v":1,"t":"U Sinajskoj pustinji, u Šatoru sastanka, reče Jahve Mojsiju prvoga dana drugoga mjeseca, druge godine po izlasku iz zemlje egipatske:"},{"v":2,"t":"“Obavite popis sve zajednice izraelske po rodovima i porodicama, navodeći imena svih muškaraca, glavu po glavu."},{"v":3,"t":"Od dvadeset godina naviše, za borbu sposobne u Izraelu, ti i Aron pobilježite prema njihovim jedinicama."},{"v":4,"t":"Neka s vama bude po jedan čovjek od svakoga plemena, glavari svoga pradjedovskog doma."},{"v":5,"t":"Ovo su imena ljudi koji će vam pomagati: Elisur, sin Šedeurov, za pleme Rubenovo;"},{"v":6,"t":"Šelumiel, sin Surišadajev, za pleme Šimunovo;"},{"v":7,"t":"Nahšon, sin Aminadabov, za pleme Judino;"},{"v":8,"t":"Netanel, sin Suarov, za pleme Jisakarovo;"},{"v":9,"t":"Eliab, sin Helonov, za pleme Zebulunovo."},{"v":10,"t":"Za Josipove sinove: Elišama, sin Amihudov, za pleme Efrajimovo; Gamliel, sin Pedahsurov, za pleme Manašeovo;"},{"v":11,"t":"Abidan, sin Gidonijev, za pleme Benjaminovo;"},{"v":12,"t":"Ahiezer, sin Amišadajev, za pleme Danovo;"},{"v":13,"t":"Pagiel, sin Okranov, za pleme Ašerovo;"},{"v":14,"t":"Elijasaf, sin Deuelov, za pleme Gadovo;"},{"v":15,"t":"Ahira, sin Enanov, za pleme Naftalijevo.”"},{"v":16,"t":"To bijahu sazivači zajednice, knezovi pradjedovskih plemena i glavari rodova izraelskih."},{"v":17,"t":"Mojsije i Aron onda uzmu one ljude što su po imenu bili određeni"},{"v":18,"t":"te prvoga dana drugoga mjeseca sazovu svu zajednicu. Tada se u popis prema rodovima i porodicama po redu unosio broj osoba starijih od dvadeset godina."},{"v":19,"t":"Kako je Jahve naredio Mojsiju, tako ih je on pobilježio u Sinajskoj pustinji."},{"v":20,"t":"Kad se utvrdi potomstvo Rubena, Izraelova prvorođenca, prema njegovim rodovima i porodicama, pribilježiše, glavu po glavu, imena svih muškaraca od dvadeset godina naviše, svih za borbu sposobnih."},{"v":21,"t":"Popisanih od Rubenova plemena bilo je četrdeset i šest tisuća i pet stotina."},{"v":22,"t":"Bili su popisani Šimunovi potomci prema njihovim rodovima i porodicama: pribilježiše se, glava po glava, imena svih muškaraca od dvadeset godina naviše, svih za borbu sposobnih."},{"v":23,"t":"Popisanih od Šimunova plemena bilo je pedeset i devet tisuća i tri stotine."},{"v":24,"t":"Kad se utvrdi potomstvo sinova Gadovih prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":25,"t":"Popisanih od Gadova plemena bilo je četrdeset i pet tisuća i šest stotina i pedeset."},{"v":26,"t":"Kad se utvrdi potomstvo sinova Judinih prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":27,"t":"Popisanih od Judina plemena bilo je sedamdeset i četiri tisuće i šest stotina."},{"v":28,"t":"Kad se utvrdi potomstvo sinova Jisakarovih prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":29,"t":"Popisanih od Jisakarova plemena bilo je pedeset i četiri tisuće i četiri stotine."},{"v":30,"t":"Kad se utvrdi potomstvo sinova Zebulunovih prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":31,"t":"Popisanih od Zebulunova plemena bilo je pedeset i sedam tisuća i četiri stotine."},{"v":32,"t":"Josipovi sinovi: Kad se utvrdi potomstvo sinova Efrajimovih, prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":33,"t":"Popisanih od Efrajimova plemena bilo je četrdeset tisuća i pet stotina."},{"v":34,"t":"Kad se utvrdi potomstvo sinova Manašeovih, prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":35,"t":"Popisanih od Manašeova plemena bilo je trideset i dvije tisuće i dvjesta."},{"v":36,"t":"Kad se utvrdi potomstvo sinova Benjaminovih, prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":37,"t":"Popisanih od Benjaminova plemena bilo je trideset i pet tisuća i četiri stotine."},{"v":38,"t":"Kad se utvrdi potomstvo sinova Danovih, prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":39,"t":"Popisanih od Danova plemena bilo je šezdeset i dvije tisuće i sedam stotina."},{"v":40,"t":"Kad se utvrdi potomstvo sinova Ašerovih, prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":41,"t":"Popisanih od Ašerova plemena bila je četrdeset i jedna tisuća i pet stotina."},{"v":42,"t":"Kad se utvrdi potomstvo sinova Naftalijevih, prema njihovim rodovima i porodicama, pribilježiše se, glava po glava, imena onih od dvadeset godina i više, svih za borbu sposobnih."},{"v":43,"t":"Popisanih od Naftalijeva plemena bilo je pedeset i tri tisuće i četiri stotine."},{"v":44,"t":"To su oni koje popisaše Mojsije i Aron sa dvanaest knezova izraelskih, po jedan na svaki pradjedovski dom."},{"v":45,"t":"Bili su popisani svi Izraelci, prema pradjedovskim domovima, od dvadeset godina i više, svi za borbu sposobni u Izraelu."},{"v":46,"t":"Bilo je, dakle, svih popisanih šest stotina i tri tisuće i pet stotina i pedeset."},{"v":47,"t":"Među te nisu se ubrojili Levijevci prema svojem pradjedovskom plemenu."},{"v":48,"t":"Jahve je, naime, rekao Mojsiju:"},{"v":49,"t":"“Nipošto nemoj popisivati Levijeva plemena niti ga unosi u popis Izraelaca."},{"v":50,"t":"Nego ti sam odredi Levijevce za službu u Prebivalištu svjedočanstva; za sav njegov namještaj i sve što na nj spada; neka oni nose Prebivalište i sav njegov namještaj; neka oni u njemu poslužuju i oko njega tabore."},{"v":51,"t":"Kad se Prebivalište mora premještati, neka ga Levijevci rastave; a kad se s Prebivalištem treba utaboriti, neka ga Levijevci opet podignu. Svjetovnjak koji bi mu se primakao neka se pogubi."},{"v":52,"t":"Neka Izraelci logoruju svatko u svome taboru; svatko kod svoje zastave, po četama."},{"v":53,"t":"Levijevci neka borave oko Prebivališta svjedočanstva, da se gnjev ne obori na izraelsku zajednicu. Neka tako Levijevci stražu straže oko Prebivališta svjedočanstva.”"},{"v":54,"t":"Izraelci učine kako je Jahve Mojsiju naredio. U svemu tako urade."}]},"2":{"hr":[{"v":1,"t":"Jahve reče Mojsiju i Aronu:"},{"v":2,"t":"“Neka Izraelci logoruju svatko kod svoje zastave, pod znakovima svojih pradjedovskih domova; neka se utabore oko Šatora sastanka, ali malo podalje."},{"v":3,"t":"Sprijeda, s istočne strane, zastava Judina tabora, prema njihovim četama. Glavar je Judinih potomaka Nahšon, sin Aminadabov."},{"v":4,"t":"Njegova vojska broji sedamdeset i četiri tisuće i šest stotina popisanih."},{"v":5,"t":"Do njega neka taboruje Jisakarovo pleme. Glavar je Jisakarovih potomaka Netanel, sin Suarov."},{"v":6,"t":"Njegova vojska broji pedeset četiri tisuće i četiri stotine popisanih."},{"v":7,"t":"Onda pleme Zebulunovo. Glavar je Zebulunovih potomaka Eliab, sin Helonov."},{"v":8,"t":"Njegova vojska broji pedeset i sedam tisuća i četiri stotine popisanih."},{"v":9,"t":"Prema njihovim četama, svih je upisanih u Judinu taboru sto osamdeset i šest tisuća i četiri stotine. Neka oni prvi stupaju!"},{"v":10,"t":"S juga je zastava tabora Rubenova, prema njihovim četama. Glavar je Rubenovih potomaka Elisur, sin Šedeurov."},{"v":11,"t":"Njegova vojska broji četrdeset i šest tisuća i pet stotina popisanih."},{"v":12,"t":"Do njega neka taboruje pleme Šimunovo. Glavar je Šimunovih potomaka Šelumiel, sin Surišadajev."},{"v":13,"t":"Njegova vojska broji pedeset i devet tisuća i tri stotine popisanih."},{"v":14,"t":"Onda pleme Gadovo. Glavar je Gadovih potomaka Elijasaf, sin Deuelov."},{"v":15,"t":"Njegova vojska broji četrdeset i pet tisuća šest stotina i pedeset popisanih."},{"v":16,"t":"Prema njihovim četama, svih je upisanih u taboru Rubenovu sto pedeset i jedna tisuća četiri stotine i pedeset. Neka oni stupaju drugi!"},{"v":17,"t":"Potom neka ide Šator sastanka, tako da tabor levitski bude usred drugih tabora. Kako taboruju, onako neka i stupaju: svatko pod svojom zastavom."},{"v":18,"t":"Sa zapada, zastava tabora Efrajimova, prema njihovim četama. Glavar je Efrajimovih potomaka Elišama, sin Amihudov."},{"v":19,"t":"Njegova vojska broji četrdeset tisuća i pet stotina popisanih."},{"v":20,"t":"Do njega je pleme Manašeovo. Glavar je Manašeovih potomaka Gamliel, sin Pedahsurov."},{"v":21,"t":"Njegova vojska broji trideset i dvije tisuće i dvjesta popisanih."},{"v":22,"t":"Onda je pleme Benjaminovo. Glavar je potomaka Benjaminovih Abidan, sin Gidonijev."},{"v":23,"t":"Njegova vojska broji trideset i pet tisuća i četiri stotine popisanih."},{"v":24,"t":"Prema njihovim četama, svih je upisanih u Efrajimovu taboru sto i osam tisuća i sto. Oni neka stupaju treći!"},{"v":25,"t":"Sa sjevera, zastava tabora Danova, prema njihovim četama. Glavar je Danovih potomaka Ahiezer, sin Amišadajev."},{"v":26,"t":"Njegova vojska broji šezdeset i dvije tisuće i sedam stotina popisanih."},{"v":27,"t":"Do njega neka se utabori pleme Ašerovo. Glavar je Ašerovih potomaka Pagiel, sin Okranov."},{"v":28,"t":"Njegova vojska broji četrdeset i jednu tisuću i pet stotina popisanih."},{"v":29,"t":"Onda pleme Naftalijevo. Glavar je Naftalijevih potomaka Ahira, sin Enanov."},{"v":30,"t":"Njegova vojska broji pedeset i tri tisuće i četiri stotine popisanih."},{"v":31,"t":"Svih je popisanih u taboru Danovu sto pedeset i sedam tisuća i šest stotina. Neka oni stupaju posljednji pod svojim zastavama.”"},{"v":32,"t":"To su popisani Izraelci prema pradjedovskim domovima. Svih je upisanih u taborima, po njihovim četama, šest stotina i tri tisuće i pet stotina i pedeset."},{"v":33,"t":"Levijevci nisu bili upisivani s Izraelcima, kako je Jahve naredio Mojsiju."},{"v":34,"t":"U svemu su Izraelci učinili kako je Jahve naredio Mojsiju. Tako su taborovali pod svojim zastavama i tako išli, svatko prema svom rodu i porodici."}]},"3":{"hr":[{"v":1,"t":"Ovo je potomstvo Aronovo i Mojsijevo iz vremena kad je Jahve Mojsiju govorio na Sinajskom brdu."},{"v":2,"t":"Ovo su bila imena Aronovih sinova: prvorođenac Nadab, zatim Abihu, Eleazar i Itamar."},{"v":3,"t":"To su imena Aronovih sinova, svećenika pomazanih, za svećeništvo posvećenih."},{"v":4,"t":"Ali Nadab i Abihu umriješe pred Jahvom kad su u Sinajskoj pustinji pred njim prinosili neposvećenu vatru. Kako nisu imali sinova, to su Eleazar i Itamar služili kao svećenici u nazočnosti svoga oca Arona."},{"v":5,"t":"Jahve reče Mojsiju:"},{"v":6,"t":"“Dozovi pleme Levijevo neka stane pred svećenika Arona. Neka mu poslužuju;"},{"v":7,"t":"neka vrše njegovu dužnost i dužnost sve zajednice pred Šatorom sastanka, služeći Prebivalištu."},{"v":8,"t":"Neka se brinu za sav namještaj u Šatoru sastanka, za dužnost sinova izraelovih, i obavljaju službu u Prebivalištu."},{"v":9,"t":"Podaj levite Aronu i njegovim sinovima. Neka mu ih Izraelci potpuno daruju."},{"v":10,"t":"Arona i njegove sinove postavi da vrše svoju svećeničku službu. A svjetovnjak koji bi se tome približio neka se pogubi.”"},{"v":11,"t":"Jahve reče Mojsiju:"},{"v":12,"t":"“Ja, evo, uzimam Levijevce između Izraelaca namjesto svih prvorođenaca - onih koji otvaraju materinju utrobu kod Izraelaca. Moji su, dakle, Levijevci!"},{"v":13,"t":"Meni, naime, pripada svaki prvorođenac. Onoga dana kad sam pobio sve prvence u zemlji egipatskoj, sebi sam posvetio sve prvorođence u Izraelu - i od ljudi i od stoke. Oni su moji. Ja sam Jahve.”"},{"v":14,"t":"Jahve reče Mojsiju u Sinajskoj pustinji:"},{"v":15,"t":"“Popiši Levijevce po njihovim porodicama i rodovima; popiši sve muškarce od jednoga mjeseca i više.”"},{"v":16,"t":"Na zapovijed Jahvinu Mojsije ih popisa, kako mu je bilo naređeno."},{"v":17,"t":"Ovo su poimenice bili sinovi Levijevi: Geršon, Kehat i Merari."},{"v":18,"t":"A ovo su imena Geršonovih sinova po njihovim rodovima: Libni i Šimi."},{"v":19,"t":"A sinovi su Kehatovi po svojim rodovima: Amram, Jishar, Hebron i Uziel."},{"v":20,"t":"Sinovi su Merarijevi po svojim rodovima: Mahli i Muši. To su Levijevi rodovi po svojim porodicama."},{"v":21,"t":"Od Geršona lozu vuče rod Libnijev i rod Šimijev. To su rodovi Geršonovaca."},{"v":22,"t":"Njih je u popisu svih muškaraca od jednoga mjeseca naviše ubilježeno sedam tisuća i pet stotina."},{"v":23,"t":"Rodovi Geršonovaca taborovali su za Prebivalištem prema zapadu."},{"v":24,"t":"Glava porodice Geršonovaca bijaše Elijasaf, sin Laelov."},{"v":25,"t":"Geršonovci su se u Šatoru sastanka brinuli za Prebivalište, za Šator i njegov krov, za zavjese na ulazu u Šator sastanka;"},{"v":26,"t":"onda za dvorišne zavjese, za zavjesu na ulazu u dvorište što je oko Prebivališta i žrtvenika, za njihova užeta i za sve što spada na tu službu."},{"v":27,"t":"Od Kehata potječe rod Amramov, rod Jisharov, rod Hebronov i rod Uzielov. To su rodovi Kehatovaca."},{"v":28,"t":"Kad se popisaše svi muškarci od jednoga mjeseca naviše, bilo ih je osam tisuća i šest stotina. Oni su se brinuli za Svetište."},{"v":29,"t":"Rodovi Kehatovaca taborovali su s južne strane Prebivališta."},{"v":30,"t":"Glava rodova u domu Kehatovu bijaše Elisafan, sin Uzielov."},{"v":31,"t":"Oni su se brinuli za Kovčeg, stol, svijećnjak, žrtvenik i sveti pribor kojim su se služili i, konačno, za zavjesu i za sve što joj pripada."},{"v":32,"t":"Vrhovni poglavar levita bio je Eleazar, sin svećenika Arona. On je vršio nadzor nad onima koji su se brinuli za Svetište."},{"v":33,"t":"Od Merarija potječe rod Mahlijev i rod Mušijev. To su Merarijevi rodovi."},{"v":34,"t":"Njih je u popisu svih muškaraca od jednoga mjeseca i više ubilježeno šest tisuća i dvije stotine."},{"v":35,"t":"Glava rodova u domu Merarijevu bijaše Suriel, sin Abihajilov. Oni su taborovali sa sjeverne strane Prebivališta."},{"v":36,"t":"Merarijevci su se brinuli za trenice Prebivališta, za njegove priječnice, za stupce i njihova podnožja, za sav njegov pribor i za sve što spada na njegovu službu."},{"v":37,"t":"Povrh toga, za stupove uokolo predvorja, njihova podnožja, kočiće i užeta."},{"v":38,"t":"Pred Prebivalištem prema istoku, pred Šatorom sastanka s istočne strane, utaborivali se Mojsije, Aron i njihovi sinovi, kojima je u ime Izraelaca bila povjerena služba u Svetištu. Svjetovnjak koji bi se približio imao se pogubiti."},{"v":39,"t":"Svih popisanih Levijevaca od jednoga mjeseca naviše, koje je na Jahvinu zapovijed po njihovim rodovima popisao Mojsije i Aron, bijaše dvadeset i dvije tisuće."},{"v":40,"t":"Jahve rekne Mojsiju: “Popiši sve muške prvorođence izraelske od jednoga mjeseca naviše te načini popis njihovih imena."},{"v":41,"t":"I levite dodijeli meni - ja sam Jahve - namjesto svih prvorođenaca izraelskih, a stoku levitsku namjesto sve prvenčadi stoke izraelske.”"},{"v":42,"t":"Tako Mojsije popiše sve prvorođence izraelske, kako mu je Jahve naredio."},{"v":43,"t":"Svih muških prvorođenaca od jednoga mjeseca naviše bijaše u popisu imena dvadeset i dvije tisuće i dvije stotine sedamdeset i tri."},{"v":44,"t":"Tada Jahve reče Mojsiju:"},{"v":45,"t":"“Uzmi levite namjesto svih prvorođenaca izraelskih, a stoku levitsku namjesto stoke njihove; leviti neka budu moji. Ja sam Jahve."},{"v":46,"t":"A za otkupninu dvjesta sedamdeset i triju izraelskih prvorođenaca što ih je više nego levita,"},{"v":47,"t":"uzmi pet šekela po glavi, uzmi ih prema hramskom šekelu: dvadeset gera - jedan šekel."},{"v":48,"t":"Onda podaj taj novac Aronu i njegovim sinovima za otkupninu onih kojih je odviše.”"},{"v":49,"t":"Tako Mojsije primi taj novac kao otkupninu za prvorođence koji su nadilazili broj onih koje su leviti otkupili."},{"v":50,"t":"Od izraelskih je prvorođenaca primio u srebru tisuću trista šezdeset i pet šekela hramske mjere."},{"v":51,"t":"Po nalogu Jahvinu Mojsije predade novac te otkupnine Aronu i njegovim sinovima, kako je Jahve Mojsiju naredio."}]},"4":{"hr":[{"v":1,"t":"Jahve reče Mojsiju i Aronu:"},{"v":2,"t":"“Izdvojite između sinova Levijevih glavare Kehatovih sinova po rodovima i porodicama njihovim:"},{"v":3,"t":"od trideset godina naviše, sve do pedeset godina - sve koji mogu ući u red da vrše službe u Šatoru sastanka."},{"v":4,"t":"A služba je Kehatovih sinova u Šatoru sastanka: briga za svetinje nad svetinjama."},{"v":5,"t":"Kad se tabor diže na put, neka uđu Aron i njegovi sinovi te skinu zaštitnu zavjesu i njom pokriju Kovčeg svjedočanstva."},{"v":6,"t":"Neka onda na nj stave pokrivalo od fine kože, a po njemu neka razastru platno, potpuno ljubičasto. Potom neka Kovčegu namjeste motke."},{"v":7,"t":"Po stolu prinošenja neka prostru ljubičasto platno. Onda neka na nj stave zdjele, žlice, krčage i vrčeve za ljevanice. Kruh neprekidnog prinošenja neka također bude na njemu."},{"v":8,"t":"To neka prekriju tamnocrvenim platnom, a preko njega neka prebace pokrivalo od fine kože. Potom neka stolu namjeste motke."},{"v":9,"t":"Neka zatim uzmu ljubičasto platno i pokriju svijećnjak za svjetlo i njegove svjetiljke, njegove usekače, njegove lugare i sve posude za ulje kojima se ono poslužuje."},{"v":10,"t":"Neka ga stave sa svim njegovim priborom na pokrivalo od fine kože pa polože na nosiljku."},{"v":11,"t":"Po zlatnom žrtveniku neka razastru ljubičasto platno i prekriju ga pokrivalom od fine kože. Potom neka mu namjeste motke."},{"v":12,"t":"Neka sad uzmu sav pribor što se upotrebljava za službu u Svetištu pa ga stave na ljubičasto platno i onda prekriju pokrivačem od fine kože. Zatim neka sve to polože na nosiljku."},{"v":13,"t":"Neka pometu pepeo sa žrtvenika i po njemu razastru crveno platno."},{"v":14,"t":"Na nj neka postave sav pribor što se upotrebljava za službu: kadionike, viljuške, lopatice i zdjele - sve posuđe za žrtvenik. Po njemu onda neka razastru pokrivalo od fine kože. Zatim neka namjeste motke."},{"v":15,"t":"Pošto Aron i njegovi sinovi završe pokrivanje Svetišta i svega svetog posuđa, u času kad imadne tabor krenuti na put, neka dođu potomci Kehatovi da to ponesu. No svetih se predmeta ne smiju doticati da ne poginu. To je dužnost Kehatovih potomaka u Šatoru sastanka."},{"v":16,"t":"A Eleazar, sin svećenika Arona, neka se brine za ulje svijećnjaka, za mirisni kad, za trajnu prinosnicu i za ulje pomazanja; neka se brine za sve Prebivalište, za sve što je u njemu - za Svetište i njegovo posuđe.”"},{"v":17,"t":"Jahve reče Mojsiju i Aronu:"},{"v":18,"t":"“Ne dopustite da nestane pleme rodova Kehatovih između levita."},{"v":19,"t":"Ovako postupajte s njima, da žive i ne izginu primičući se najvećim svetinjama: neka dođu Aron i njegovi sinovi da postave svakoga od njih na njegovu službu i uz njegovu dužnost."},{"v":20,"t":"Oni neka ne ulaze ni da začas pogledaju Svetište da ne bi poginuli.”"},{"v":21,"t":"Jahve reče Mojsiju:"},{"v":22,"t":"“Popiši i Geršonove sinove po njihovim porodicama i njihovim rodovima, od trideset godina naviše, sve do pedesete godine;"},{"v":23,"t":"popiši ih sve koji mogu ići u red da vrše službu u Šatoru sastanka."},{"v":24,"t":"A ovo je služba rodova Geršonovaca pri radu i prenošenju:"},{"v":25,"t":"neka nose zavjese Prebivališta, Šator sastanka s njegovim krovom, pokrivalo od fine kože što je povrh njega, i zavjesu na ulazu u Šator sastanka;"},{"v":26,"t":"onda, dvorišne zavjese, zavjesu s vrata na ulazu u predvorje što opkoljuje Prebivalište i žrtvenik, konopce i sav pribor za njihovu službu; što god treba oko tih stvari raditi, neka učine."},{"v":27,"t":"Neka Geršonovci obavljaju sve svoje dužnosti - sve što imaju nositi i sve što imaju raditi - po nalogu Arona i njegovih sinova. Njihovoj brizi povjerite sve što treba da nose."},{"v":28,"t":"To je služba rodova Geršonovaca u Šatoru sastanka. Njihova služba neka bude pod vodstvom Itamara, sina svećenika Arona.”"},{"v":29,"t":"“Sinove Merarijeve popiši po rodovima i porodicama njihovim."},{"v":30,"t":"Popiši ih od trideset godina naviše, sve do pedeset godina, koji mogu ući u red da vrše službu u Šatoru sastanka."},{"v":31,"t":"Za sve njihove službe u Šatoru sastanka dužnost im je da nose trenice za Prebivalište, njegove priječnice, njegove stupce i njegova podnožja;"},{"v":32,"t":"stupce što okružuju predvorje, njihova podnožja, njihove kočiće, njihove konopce, sa svim priborom za njihovu službu. Poimenično popišite predmete što su im povjereni da ih nose."},{"v":33,"t":"To je služba rodova Merarijevaca u svemu što imaju činiti u Šatoru sastanka pod vodstvom Itamara, sina svećenika Arona.”"},{"v":34,"t":"Mojsije, Aron i glavari zajednice popisali su Kehatove sinove po njihovim rodovima i porodicama -"},{"v":35,"t":"sve koji mogu ući u red da vrše službu u Šatoru sastanka, od trideset godina naviše, sve do pedeset godina."},{"v":36,"t":"I popisanih po njihovim rodovima bijaše dvije tisuće sedam stotina i pedeset."},{"v":37,"t":"To je popis rodova Kehatovaca, svih koji su služili u Šatoru sastanka, a koje popisa Mojsije i Aron na zapovijed što je Jahve dade Mojsiju."},{"v":38,"t":"Popisanih sinova Geršonovih po njihovim rodovima i porodicama,"},{"v":39,"t":"od trideset godina naviše, sve do pedeset godina, svih koji mogu ući u red da vrše službu u Šatoru sastanka -"},{"v":40,"t":"popisanih, dakle, po njihovim rodovima i porodicama bijaše dvije tisuće šest stotina i pedeset."},{"v":41,"t":"To je popis rodova Geršonovaca, svih koji su služili u Šatoru sastanka, a koje popisa Mojsije i Aron na Jahvinu zapovijed."},{"v":42,"t":"Popis rodova Merarijevih sinova po njihovim rodovima i porodicama,"},{"v":43,"t":"od trideset godina naviše, sve do pedeset godina, svih koji mogu ući u red da vrše službu u Šatoru sastanka -"},{"v":44,"t":"popisanih, dakle, po njihovim rodovima bijaše tri tisuće dvjesta."},{"v":45,"t":"To je popis Merarijevaca što su ga sastavili Mojsije i Aron na zapovijed koju je Jahve dao Mojsiju."},{"v":46,"t":"Svih, dakle, popisanih levita koje su popisali Mojsije, Aron i glavari izraelski po njihovim rodovima i porodicama, od trideset godina naviše do pedeset godina -"},{"v":47,"t":"svih koji su ušli u službu posluživanja i službu prenošenja u Šatoru sastanka -"},{"v":48,"t":"bilo je osam tisuća pet stotina i osamdeset."},{"v":49,"t":"Na zapovijed koju je Jahve dao Mojsiju svakoga su unijeli u popis prema onom u čemu je služio i što je prenosio. Popisali su ih kako je Jahve zapovjedio Mojsiju."}]},"5":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Naredi Izraelcima da iz tabora odstrane svakoga gubavca, svakoga koji imadne izljev i svakoga koji se onečisti mrtvim tijelom."},{"v":3,"t":"Odstranite i muške i ženske! Izvan tabora ih istjerajte da ne onečiste svoje tabore u kojima ja boravim među njima.”"},{"v":4,"t":"Izraelci tako učine: istjeraju ih iz tabora. Kako je Jahve rekao Mojsiju, tako Izraelci učine."},{"v":5,"t":"Jahve reče Mojsiju:"},{"v":6,"t":"“Kaži Izraelcima: Kad koji čovjek ili žena počini bilo kakav grijeh na štetu čovjeka ogriješivši se protiv Jahve, i osjeti se krivim,"},{"v":7,"t":"neka prizna počinjeni grijeh, nadoknadi štetu što bolje može te još doda tome petinu i dadne onome kome je nanio nepravdu."},{"v":8,"t":"Ako čovjek ne bi imao bližeg rođaka kome bi se nadoknada mogla uručiti, dužna nadoknada pripada Jahvi za svećenika, ne računajući u to pomirbenoga ovna kojim će svećenik izvršiti nad krivcem obred pomirenja."},{"v":9,"t":"I svaka podizanica od svih posvećenih stvari što ih Izraelci svećeniku donose njemu pripada."},{"v":10,"t":"Svakome idu stvari koje je posvetio; i neka svećeniku bude ono što njemu tko dadne.”"},{"v":11,"t":"Jahve reče Mojsiju:"},{"v":12,"t":"“Govori Izraelcima i reci im: Ako nekome žena pođe stranputicom te mu se iznevjeri"},{"v":13,"t":"i netko s njom legne, ali to ostane sakriveno očima njezina muža i žena ostane neotkrivena iako se oskvrnula te protiv nje ne bude svjedoka budući da u činu nije bila uhvaćena -"},{"v":14,"t":"i sad muža obuzme duh ljubomore i on postane ljubomoran na svoju ženu koja se oskvrnula; ili ako ga spopadne duh ljubomore te postane ljubomoran na svoju ženu a da se ona nije oskvrnula -"},{"v":15,"t":"neka taj muž dovede svoju ženu svećeniku. Neka za nju donese prinos: desetinu efe ječmenog brašna. Neka po njemu ne polijeva ulja niti na nj stavlja tamjana, jer to je prinosnica za ljubomoru, spomen-prinosnica da podsjeti na grijeh."},{"v":16,"t":"Neka svećenik povede tu ženu i postavi je pred Jahvu."},{"v":17,"t":"Sad neka svećenik uzme posvećene vode u kakvu zemljanu posudu i, uzevši prašine što je na podu Prebivališta, neka je svećenik ubaci u vodu."},{"v":18,"t":"Pošto je svećenik postavio ženu pred Jahvu, neka joj otkrije glavu a na njezine ruke stavi spomen-prinosnicu, to jest žitnu prinosnicu za ljubomoru, s svećenik neka drži u ruci vodu gorčine i prokletstva."},{"v":19,"t":"Zatim neka svećenik ženu zakune. Neka joj reče: 'Ako nikad čovjek s tobom nije ležao te ako nisi išla stranputicom i oskvrnula se dok si bila pod vlašću svoga muža, budi pošteđena od ove vode gorčine i prokletstva!"},{"v":20,"t":"Ali ako si išla stranputicom dok si bila pod vlašću svoga muža te se oskvrnula; ako je koji čovjek osim tvoga muža legao s tobom ...'"},{"v":21,"t":"Ovdje neka svećenik zakune ženu ovom kletvom: neka joj rekne: Jahve te postavio za prokletstvo i kletvu među tvojim narodom, učinio da ti uvene rodnica i da ti se utroba nadme!"},{"v":22,"t":"Neka ova voda prokletstva zađe u tvoju utrobu! Trbuh ti se od nje naduo, a rodnica uvenula! - A žena neka poprati: Amen! Amen!"},{"v":23,"t":"Potom neka ta prokletstva svećenik napiše na list pa ih ispere u vodu gorčine."},{"v":24,"t":"Onda neka ženu napoji vodom gorčine i prokletstva, da bi se voda gorčine po njoj razišla i napunila je gorkošću."},{"v":25,"t":"Neka svećenik onda uzme iz ženine ruke prinosnicu za ljubomoru, prinese je pred Jahvom kao žrtvu prikaznicu te je donese na žrtvenik."},{"v":26,"t":"Zagrabivši od prinosnice punu pregršt kao spomen-žrtvu, neka to sažeže u kad na žrtveniku. Napokon, neka ženu napoji vodom."},{"v":27,"t":"Pošto je napoji vodom, bude li oskvrnuta iznevjerivši se svome mužu, voda prokletstva ući će u nju i napunit će je gorčinom; njezina će se utroba naduti a rodnica uvenuti - ta će žena postati prokletstvom u svome narodu."},{"v":28,"t":"A ako žena ne bude oskvrnuta nego nevina, neće joj biti ništa i imat će djece."},{"v":29,"t":"To je obred u slučaju ljubomore, kad žena pođe stranputicom i oskvrne se dok je pod vlašću svoga muža;"},{"v":30,"t":"ili kad kojega čovjeka obuzme duh ljubomore te postane ljubomoran na svoju ženu. Neka, dakle, postavi svoju ženu pred Jahvu, a svećenik neka nad njom izvrši sav ovaj obred."},{"v":31,"t":"Neka je muž slobodan od krivnje, a žena neka snosi svoju krivnju.”"}]},"6":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Govori Izraelcima i reci im: 'Ako tko, bilo čovjek ili žena, položi nazirejski zavjet te se posveti Jahvi,"},{"v":3,"t":"neka se suzdržava od vina i svakoga opojnog pića. Neka ne pije ni ukiseljena vina niti ukiseljena opojnog pića; a niti kakva soka od grožđa neka ne pije; neka ne jede grožđa, ni svježa ni suha."},{"v":4,"t":"Sve vrijeme svoga nazireata ne smije jesti ništa što rađa lozov trs - od zelena grožđa do komine.'"},{"v":5,"t":"Sve dok traje njegov nazirejski zavjet, neka britva ne prelazi preko njegove glave; dok se ne navrši vrijeme što ga je Jahvi zavjetovao, neka bude posvećen i pusti kose da mu slobodno rastu na glavi."},{"v":6,"t":"Za sve vrijeme svoga zavjeta Jahvi neka se ne primiče nikakvu mrtvacu."},{"v":7,"t":"Neka se ne onečišćuje ni zbog svoga oca, ni zbog svoje majke, svoga brata ili svoje sestre ako bi umrli, jer na svojoj glavi nosi posvećenje svoga Boga."},{"v":8,"t":"Sve vrijeme svoga nazireata on je posvećen Jahvi."},{"v":9,"t":"Umre li tko nenadanom smrću pokraj njega, onečistivši tako njegovu posvećenu glavu, neka na dan svoga očišćenja obrije svoju glavu - neka je obrije sedmoga dana."},{"v":10,"t":"A osmoga dana neka donese svećeniku, na ulazu u Šator sastanka, dvije grlice ili dva golubića."},{"v":11,"t":"Neka svećenik prinese jedno kao žrtvu okajnicu, a drugo kao žrtvu paljenicu, zatim neka nad njim izvrši obred pomirenja zbog ljage kojom se okaljao uz mrtvaca. Toga dana neka posveti svoju glavu;"},{"v":12,"t":"neka zavjetuje Jahvi dane svoga nazireata; neka donese jednogodišnjeg janjca kao žrtvu naknadnicu. Prijašnje vrijeme neka se ne računa, jer je njegov nazireat bio oskvrnjen."},{"v":13,"t":"Ovo je obred za nazirejca: na dan kad se navrši vrijeme njegova nazireata, neka ga dovedu na ulaz Šatora sastanka."},{"v":14,"t":"Kao svoj prinos neka Jahvi donese: jednogodišnjeg janjca bez mane za žrtvu paljenicu; jednogodišnje žensko janje, bez mane, za žrtvu okajnicu; jednoga ovna, bez mane, za žrtvu pričesnicu;"},{"v":15,"t":"nadalje, košaru neukvasanih pogača od najboljeg brašna, u ulju zamiješenih i neukvasanih kolača, namazanih uljem, s njihovim prinosnicama i ljevanicama."},{"v":16,"t":"Svećenik, pošto to donese pred Jahvu, neka prinese njegovu okajnicu i paljenicu."},{"v":17,"t":"Zatim neka prinese ovna Jahvi kao žrtvu pričesnicu zajedno s košarom neukvasanih pogača. I njegovu prinosnicu i njegovu ljevanicu neka prinese svećenik."},{"v":18,"t":"Na ulazu u Šator sastanka neka nazirejac obrije svoju posvećenu glavu i, uzevši uvojke sa svoje posvećene glave, neka ih stavi na vatru što gori pred žrtvom pričesnicom."},{"v":19,"t":"Zatim neka svećenik uzme kuhano pleće ovna, jednu neukvasanu pogaču iz košare i jedan neukvasani kolač i stavi to na ruke nazirejcu pošto ovaj obrije svoje posvećene kose."},{"v":20,"t":"Neka to svećenik prinese kao žrtvu prikaznicu pred Jahvom. To je svetinja što pripada svećeniku, osim grudi prikaznice i stegna podizanice. Poslije toga nazirejac može piti vina.”"},{"v":21,"t":"Ovo je obred nazirejca, ne računajući ono što bi još mogla prinijeti njegova ruka. Ako je povrh svoga nazireata obećao kakav dar, neka povrh obreda svoga nazireata učini kako je zavjetovao."},{"v":22,"t":"Jahve reče Mojsiju:"},{"v":23,"t":"“Reci Aronu i njegovim sinovima: 'Ovako blagoslivljajte Izraelce govoreći im:"},{"v":24,"t":"Neka te blagoslovi Jahve i neka te čuva!"},{"v":25,"t":"Neka te Jahve licem svojim obasja, milostiv ti bude!"},{"v":26,"t":"Neka pogled svoj Jahve svrati na te i mir ti donese!' Tako neka stavljaju moje ime nad sinove Izraelove, i ja ću ih blagoslivljati.”"}]},"7":{"hr":[{"v":1,"t":"U onaj dan kad Mojsije završi podizanje Prebivališta i kad ga pomaza i posveti sa svim njegovim posuđem, a tako i žrtvenik sa svim njegovim priborom,"},{"v":2,"t":"pristupe glavari izraelski, starješine njihovih pradjedovskih domova, to jest knezovi plemenski koji su vodili popisivanje,"},{"v":3,"t":"i dovedu svoje prinose pred Jahvu: šestora teretna kola i dvanaest volova - jedna kola za dvojicu glavara i vola za svakoga pojedinoga. Dovedu ih pred Prebivalište."},{"v":4,"t":"Tada Jahve progovori Mojsiju:"},{"v":5,"t":"“Primi to od njih za upotrebu pri službi u Šatoru sastanka; onda to podaj svakome levitu prema njegovoj službi.”"},{"v":6,"t":"Mojsije uze kola i volove pa ih dade levitima."},{"v":7,"t":"Dvoja kola i četiri vola dade Geršonovcima prema njihovoj službi,"},{"v":8,"t":"a četvera kola i osam volova dade Merarijevcima prema njihovoj službi pod vodstvom Itamara, sina svećenika Arona."},{"v":9,"t":"Kehatovcima nije dao ništa, jer je njihova zadaća bila nositi posvećene predmete na ramenima."},{"v":10,"t":"Tada glavari prinesu prinos za posvetu žrtvenika na dan njegova pomazanja. Dok su glavari prinosili svoje prinose pred žrtvenik,"},{"v":11,"t":"Jahve progovori Mojsiju: “Svakoga dana neka po jedan glavar donese svoj prinos za posvetu žrtvenika!”"},{"v":12,"t":"Prvoga dana donese svoj prinos Nahšon, sin Aminadabov, od plemena Judina."},{"v":13,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela i jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; jedno i drugo bijaše napunjeno najboljim brašnom, zamiješenim u ulju, za prinosnicu."},{"v":14,"t":"Onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":15,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":16,"t":"jedan jarac za žrtvu okajnicu,"},{"v":17,"t":"a za žrtvu pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Nahšona, Aminadabova sina."},{"v":18,"t":"Drugoga dana donese svoj prinos Netanel, sin Suarov, glavar Jisakarovaca."},{"v":19,"t":"Za svoj prinos donio je: jednu srebrnu zdjelu tešku sto trideset šekela, jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje puno najboljeg brašna, zamiješena u ulju, za prinosnicu;"},{"v":20,"t":"onda jednu zlatnu posudicu od deset šekela punu tamjana;"},{"v":21,"t":"jednog junca, jednoga ovna, jedno janje od godinu dana za paljenicu;"},{"v":22,"t":"jednog jarca za okajnicu,"},{"v":23,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Netanela, Suarova sina."},{"v":24,"t":"Trećega dana donese svoj prinos glavar Zebulunovaca, Eliab, sin Helonov."},{"v":25,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela i jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje puno najboljeg brašna, zamiješena u ulju, za prinosnicu;"},{"v":26,"t":"jedna zlatna posudica puna tamjana;"},{"v":27,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":28,"t":"jedan jarac za okajnicu,"},{"v":29,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Eliaba, Helonova sina."},{"v":30,"t":"Četvrtog dana donese svoj prinos glavar Rubenovaca, Elisur, sin Šedeurov."},{"v":31,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela, jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje puno najboljeg brašna, zamiješena u ulju, za prinosnicu;"},{"v":32,"t":"onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":33,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":34,"t":"jedan jarac za okajnicu,"},{"v":35,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Elisura, Šedeurova sina."},{"v":36,"t":"Petoga dana donese svoj prinos glavar Šimunovaca, Šelumiel, sim Surišadajev."},{"v":37,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela, jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje napunjeno najboljim brašnom, zamiješenim u ulju, za prinosnicu;"},{"v":38,"t":"onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":39,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":40,"t":"jedan jarac za okajnicu,"},{"v":41,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Šelumiela, Surišadajeva sina."},{"v":42,"t":"Šestoga dana donese svoj prinos glavar Gadovaca, Elijasaf, sin Deuelov."},{"v":43,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela, jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje napunjeno najboljim brašnom, zamiješenim u ulju, za prinosnicu;"},{"v":44,"t":"onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":45,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":46,"t":"jedan jarac za okajnicu,"},{"v":47,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Elijasafa, Deuelova sina."},{"v":48,"t":"Sedmoga dana donese svoj prinos glavar Efrajimovaca, Elišama, sin Amihudov."},{"v":49,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela i jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje puno najboljeg brašna, zamiješena u ulju, za prinosnicu;"},{"v":50,"t":"onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":51,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu,"},{"v":52,"t":"jedan jarac za okajnicu,"},{"v":53,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Elišama, Amihudova sina."},{"v":54,"t":"Osmoga dana donese svoj prinos glavar Manašeovaca, Gamliel, sin Pedahsurov."},{"v":55,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela i jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje napunjeno najboljim brašnom, zamiješenim u ulju, za prinosnicu;"},{"v":56,"t":"onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":57,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":58,"t":"jedan jarac za okajnicu,"},{"v":59,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Gamliela, Pedahsurova sina."},{"v":60,"t":"Devetoga dana donese svoj prinos glavar Benjaminovaca, Abidan, sin Gidonijev."},{"v":61,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela i jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje napunjeno najboljim brašnom, zamiješenim u ulju, za prinosnicu;"},{"v":62,"t":"onda jedna zlatna posudica od deset šekela puna tamjana,"},{"v":63,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":64,"t":"jedan jarac za okajnicu,"},{"v":65,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Abidana, Gidonijeva sina."},{"v":66,"t":"Desetoga dana donese svoj prinos glavar Danovaca, Ahiezer, sin Amišadajev."},{"v":67,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela i jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje napunjeno najboljim brašnom, zamiješenim u ulju, za prikaznicu;"},{"v":68,"t":"onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":69,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":70,"t":"jedan jarac za okajnicu,"},{"v":71,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Ahiezera, Amišadajeva sina."},{"v":72,"t":"Jedanaestoga dana donese svoj prinos glavar Ašerovaca, Pagiel, sin Okranov."},{"v":73,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela i jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje napunjeno najboljim brašnom, zamiješenim u ulju, za prinosnicu;"},{"v":74,"t":"onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":75,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":76,"t":"jedan jarac za okajnicu,"},{"v":77,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Pagiela, Okranova sina."},{"v":78,"t":"Dvanaestoga dana donese svoj prinos glavar Naftalijevaca, Ahira, sin Enanov."},{"v":79,"t":"Njegov je prinos bio: jedna srebrna zdjela teška sto trideset šekela i jedan srebrni kotlić od sedamdeset šekela, prema hramskom šekelu; oboje napunjeno najboljim brašnom, zamiješenim u ulju, za prinosnicu;"},{"v":80,"t":"onda jedna zlatna posudica od deset šekela puna tamjana;"},{"v":81,"t":"jedan junac, jedan ovan, jedno janje od godinu dana za paljenicu;"},{"v":82,"t":"jedan jarac za okajnicu,"},{"v":83,"t":"a za pričesnicu: dva vola, pet ovnova, pet kozlića i pet jednogodišnjih janjaca. To je bio prinos Ahire, Enanova sina."},{"v":84,"t":"To su bili prinosi glavara izraelskih za posvetu žrtvenika na dan kad bijaše pomazan: dvanaest srebrnih zdjela, dvanaest srebrnih kotlića i dvanaest zlatnih posudica."},{"v":85,"t":"Svaka srebrna zdjela težila je sto trideset šekela; svaki kotlić sedamdeset šekela. Svega srebra u posuđu bilo je dvije tisuće i četiri stotine hramskih šekela."},{"v":86,"t":"Zlatnih posudica punih tamjana bilo je dvanaest, svaka posudica težila je deset hramskih šekela. Sve zlato u posudicama težilo je sto dvadeset šekela."},{"v":87,"t":"Sve stoke za paljenicu: dvanaest junaca, dvanaest ovnova, dvanaest jednogodišnjih janjaca s njihovim prinosima. Za okajnicu dvanaest jaraca."},{"v":88,"t":"Sve stoke za pričesnicu: dvadeset i četiri vola, šezdeset ovnova, šezdeset kozlića i šezdeset janjaca od godine dana. To je bio prinos za posvetu žrtvenika pošto bijaše pomazan."},{"v":89,"t":"Kad bi Mojsije ulazio u Šator sastanka da razgovara s Njim, slušao bi glas kako mu govori ozgo s Pomirilišta što je bilo na Kovčegu svjedočanstva, među dva kerubina. Tada bi mu govorio."}]},"8":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Govori Aronu i reci mu: 'Kad budeš palio svjetionice, neka sedam svjetionica svijetli na prednjoj strani svijećnjaka.'”"},{"v":3,"t":"Aron i učini tako: smjesti svjetionice na prednju stranu svijećnjaka, kako je Jahve Mojsiju naredio."},{"v":4,"t":"Svijećnjak bijaše skovan od zlata; skovan od svoga podnožja do svoje čaške. Svijećnjak je bio napravljen prema uzorku što ga je Jahve pokazao Mojsiju."},{"v":5,"t":"Jahve reče Mojsiju:"},{"v":6,"t":"“Uzmi levite između Izraelaca i očisti ih!"},{"v":7,"t":"Ovako s njima postupi da ih očistiš: poškropi ih vodom za okajavanje; a oni neka se obriju po svemu svome tijelu, neka operu svoju odjeću i bit će čisti."},{"v":8,"t":"Neka zatim uzmu jednog junca i prinosnicu od najboljeg brašna, zamiješena u ulju. A ti uzmi drugog junca za okajnicu."},{"v":9,"t":"Dovedi onda levite pred Šator sastanka i skupi svu izraelsku zajednicu."},{"v":10,"t":"Kad dovedeš levite pred Jahvu, neka Izraelci stave na njih svoje ruke."},{"v":11,"t":"Neka zatim Aron prinese levite, kao prikaznicu pred Jahvom, u ime Izraelaca. Tako će njihov posao biti da služe Jahvi."},{"v":12,"t":"Neka potom leviti stave svoje ruke juncima na glave; onda jednoga prinesi kao okajnicu, a drugoga kao paljenicu Jahvi, da se izvrši obred pomirenja nad levitima."},{"v":13,"t":"Stavivši levite pred Arona i njegove sinove, prikaži ih Jahvi žrtvom prikaznicom."},{"v":14,"t":"Odvoji tako levite između Izraelaca da budu moji."},{"v":15,"t":"Poslije toga, pošto ih očistiš i prineseš žrtvom prikaznicom, neka leviti uđu u službu Šatora sastanka."},{"v":16,"t":"Jer oni su između Izraelaca meni potpuno darovani; njih sam sebi uzeo namjesto svih koji otvaraju majčinu utrobu, svih izraelskih prvorođenaca."},{"v":17,"t":"Svako, naime, prvorođenče među Izraelcima, kako čedo tako i živinče, moje je; sebi sam ih posvetio onoga dana kad sam pobio svu prvorođenčad u zemlji egipatskoj."},{"v":18,"t":"Tako sam uzeo levite namjesto svih izraelskih prvorođenaca."},{"v":19,"t":"I predao sam levite između Izraelaca kao dar Aronu i njegovim sinovima da mjesto Izraelaca obavljaju službu u Šatoru sastanka; da nad njima obavljaju obred pomirenja, tako da kakva nedaća ne bi pogodila Izraelce što bi se približili Svetištu.”"},{"v":20,"t":"Mojsije, Aron i sva izraelska zajednica učine tako s levitima; kako je Jahve naredio Mojsiju za levite, tako im Izraelci i učine."},{"v":21,"t":"Leviti se očiste i operu svoju odjeću; onda ih Aron prinese pred Jahvu žrtvom prikaznicom. Aron nad njima obavi obred pomirenja da ih očisti."},{"v":22,"t":"Poslije toga uđu leviti u službu u Šator sastanka, u nazočnosti Arona i njegovih sinova. Kako je Jahve naredio Mojsiju za levite, tako su s njima i uradili."},{"v":23,"t":"Jahve reče Mojsiju:"},{"v":24,"t":"“I ovo se tiče levita: od dvadeset i pet godina naviše neka leviti po redu preuzimaju službu u Šatoru sastanka."},{"v":25,"t":"A kad kome bude pedeset godina, neka istupi iz službe i neka više ne služi."},{"v":26,"t":"Ali može pomagati svojoj braći u vršenju njihovih dužnosti u Šatoru sastanka, no sam ne mora vršiti službe. Tako postupi prema levitima za njihove dužnosti!”"}]},"9":{"hr":[{"v":1,"t":"Prvoga mjeseca druge godine nakon izlaska iz zemlje egipatske Jahve reče Mojsiju u Sinajskoj pustinji:"},{"v":2,"t":"“Neka Izraelci slave Pashu u njezino vrijeme."},{"v":3,"t":"Slavite je u njezino vrijeme, u suton, četrnaestoga dana ovoga mjeseca; slavite je prema svim njezinim propisima i običajima.”"},{"v":4,"t":"Tako Mojsije reče Izraelcima da slave Pashu."},{"v":5,"t":"I oni su je slavili u Sinajskoj pustinji, u suton, prvoga mjeseca, četrnaestoga dana u mjesecu. Kako je god Jahve Mojsiju naredio, tako su Izraelci i učinili."},{"v":6,"t":"A bijaše ljudi onečišćenih mrtvacem; ti nisu mogli slaviti Pashu onoga dana. Dođu tako pred Mojsija i Arona istoga dana"},{"v":7,"t":"pa reknu: “Mrtvacem smo se onečistili; ipak, zašto bi nam bilo uskraćeno prinositi Jahvi žrtvu u njezino vrijeme usred Izraelovih sinova?”"},{"v":8,"t":"Mojsije im reče: “Strpite se da čujem što će Jahve za vas odrediti.”"},{"v":9,"t":"I Jahve reče Mojsiju:"},{"v":10,"t":"“Ovako kaži Izraelcima: 'Kad se tko između vas ili vaših potomaka onečisti mrtvacem ili je na daleku putu, neka ipak slavi Pashu Jahvi."},{"v":11,"t":"Neka je slave u suton četrnaestog dana drugoga mjeseca. Neka je blaguju s neukvasanim kruhom i gorkim zeljem;"},{"v":12,"t":"neka ništa od nje ne ostavljaju za ujutro; neka ni jedne kosti na njoj ne lome. Neka je slave prema propisima Pashe."},{"v":13,"t":"Onaj koji je čist a ne bude na putovanju pa ipak propusti proslaviti Pashu, neka se iskorijeni iz svoga naroda. Budući da nije prinio Jahvi žrtve u njezino vrijeme, takav neka snosi svoju krivnju."},{"v":14,"t":"Ako s vama boravi stranac i Pashu prinosi Jahvi, neka je prinosi prema propisima i običajima njezinim. Neka bude jedan zakon za vas, bio to stranac ili domorodac.'”"},{"v":15,"t":"Na dan kad je podignuto Prebivalište oblak prekri Prebivalište, Šator svjedočanstva. Od večeri do jutra stajao je u obliku ognja nad Prebivalištem."},{"v":16,"t":"Tako ga je oblak neprestano zaklanjao, a noću bijaše poput ognja."},{"v":17,"t":"Kad bi se god oblak digao sa Šatora, Izraelci bi poslije toga krenuli. A gdje bi oblak stao, tu bi se i Izraelci utaborili."},{"v":18,"t":"Na zapovijed Jahvinu Izraelci su kretali na put i na Jahvinu se zapovijed utaborivali. Sve vrijeme što bi oblak stajao nad Prebivalištem oni su taborovali."},{"v":19,"t":"Ako bi oblak dugo stajao nad Prebivalištem, Izraelci su slušali Jahvin nalog i ne bi polazili na put."},{"v":20,"t":"Ali ako bi se dogodilo da oblak ostane nad Prebivalištem malo vremena, oni bi se na Jahvinu zapovijed utaborili i na Jahvinu zapovijed opet krenuli na put."},{"v":21,"t":"Ako bi se oblak digao pošto se zadržao od večeri do jutra, oni bi tada ujutro krenuli na put. Danju ili noću, kad bi se oblak digao, oni bi krenuli na put."},{"v":22,"t":"Dva dana ili mjesec ili godinu - dok bi oblak ostajao nad Prebivalištem - Izraelci su taborovali, ne krećući na put, a čim bi se digao, oni bi krenuli."},{"v":23,"t":"Po zapovijedi Jahvinoj stajahu u taboru i po zapovijedi Jahvinoj kretahu na put. Držali su se Jahvina naloga, kako Jahve bijaše zapovjedio Mojsiju."}]},"10":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Napravi sebi dvije trube; napravi ih od kovana srebra. Neka ti služe za sazivanje zajednice i za pokretanje tabora."},{"v":3,"t":"Kad se u njih zatrubi, neka se sva zajednica skupi k tebi na ulazu u Šator sastanka."},{"v":4,"t":"Ako li se zatrubi u jednu, neka se k tebi skupe glavari izraelski, tisućnici."},{"v":5,"t":"Kad popratite trubljenje bojnim poklikom, neka krenu logori utaboreni na istočnoj strani."},{"v":6,"t":"Kad popratite trubljenje bojnim poklikom po drugi put, neka krenu logori utaboreni s južne strane: neka se trubljenje poprati bojnim poklikom da oni krenu."},{"v":7,"t":"Trubite i da skupite zajednicu, ali bez bojnog poklika."},{"v":8,"t":"Neka u trube trube svećenici, sinovi Aronovi. Neka vam to bude trajnom uredbom za vaše naraštaje."},{"v":9,"t":"Kad u svojoj zemlji pođete u rat na neprijatelja koji vas pritisne, zaorite na trube s bojnim poklikom, i Jahve, Bog vaš, sjetit će se vas i bit ćete izbavljeni od svojih neprijatelja."},{"v":10,"t":"Na dan svoje svečanosti, svojih blagdana ili svojih mjesečevih mlađaka, dok prinosite svoje paljenice i pričesnice, trubite u trube. Neka to za vas bude spomen pred Bogom vašim. Ja sam Jahve, Bog vaš.”"},{"v":11,"t":"Druge godine drugoga mjeseca dvadesetog dana u mjesecu diže se oblak iznad Prebivališta svjedočanstva."},{"v":12,"t":"Tada se Izraelci zapute iz Sinajske pustinje na svoja putovanja. Oblak se zaustavi u pustinji Paranu."},{"v":13,"t":"Tako na Jahvinu zapovijed danu Mojsiju krenuše prvi put."},{"v":14,"t":"Prva je krenula zastava tabora Judinih sinova u svojim četama. Nad njihovom vojskom bijaše Nahšon, sin Aminadabov;"},{"v":15,"t":"nad vojskom plemena Jisakarovaca stajaše Netanel, sin Suarov,"},{"v":16,"t":"a nad vojskom plemena Zebulunovaca bijaše Eliab, sin Helonov."},{"v":17,"t":"Zatim, pošto je rastavljeno Prebivalište, krenuše Geršonovci i Merarijevci noseći Prebivalište."},{"v":18,"t":"Potom krenu zastava tabora Rubenova u svojim četama. Nad njihovom vojskom bijaše Elisur, sin Šedeurov;"},{"v":19,"t":"nad vojskom plemena Šimunovaca stajao je Šelumiel, sin Surišadajev;"},{"v":20,"t":"nad vojskom plemena Gadovaca bio je Elijasaf, sin Deuelov."},{"v":21,"t":"Potom krenuše Kehatovci noseći posvećene predmete. Tako je Prebivalište bilo podignuto prije njihova dolaska."},{"v":22,"t":"Onda krenu zastava tabora Efrajimovaca u svojim četama. Nad njihovom vojskom bijaše Elišama, sin Amihudov,"},{"v":23,"t":"nad vojskom plemena Manašeovaca stajaše Gamliel, sin Pedahsurov;"},{"v":24,"t":"nad vojskom plemena Benjaminovaca bijaše Abidan, sin Gidonijev."},{"v":25,"t":"A kao zalazna straža za sve tabore krenu, u svojim četama, zastava tabora Danovaca. Nad njihovom je vojskom stajao Ahiezer, sin Amišadajev."},{"v":26,"t":"Nad vojskom plemena Ašerovaca bio je Pagiel, sin Okranov;"},{"v":27,"t":"a nad vojskom plemena Naftalijevaca bio je Ahira, sin Enanov."},{"v":28,"t":"Takav je bio red putovanja Izraelaca svrstanih u svoje čete. Tako su putovali."},{"v":29,"t":"Mojsije reče Hobabu, sinu Midjanca Reuela, Mojsijeva tasta: “Zaputili smo se u kraj o kojemu je Jahve rekao: 'Dat ću vam ga!' Pođi s nama i dobro ćemo ti činiti, jer je Jahve obećao sreću Izraelu.”"},{"v":30,"t":"“Ne idem”, odgovori mu, “nego se vraćam u svoju zemlju; k svojima se vraćam.”"},{"v":31,"t":"“Molim te, ne ostavljaj nas!” - reče. “Budući da znaš gdje nam se treba u pustinji utaboriti, valjat ćeš nam kao oči."},{"v":32,"t":"Ako s nama pođeš, dobročinstva koja nam Jahve bude udijelio s tobom ćemo dijeliti.”"},{"v":33,"t":"Od Jahvina brda putovali su tri dana hoda. Kovčeg Jahvina saveza išao je pred njima ta tri dana hoda da im potraži mjesto odmora."},{"v":34,"t":"Danju je opet Jahvin oblak bio nad njima, kako bi se iz tabora zaputili."},{"v":35,"t":"Kad bi Kovčeg polazio, Mojsije bi rekao: “Ustani, Jahve! Neprijatelji tvoji neka se rasprše! Koji tebe mrze nek' bježe pred tobom!”"},{"v":36,"t":"A kad bi se zaustavljao, popratio bi: “Vrati se, o Jahve! Izraelu ti si tisuće bezbrojne!”"}]},"11":{"hr":[{"v":1,"t":"I stade narod zlobno mrmljati u Jahvine uši. Kad to ču Jahve, planu gnjevom. Jahvin oganj izbi među njima i spali jedan kraj tabora."},{"v":2,"t":"Narod zavapi Mojsiju, a Mojsije se pomoli Jahvi i oganj se utiša."},{"v":3,"t":"Ono se mjesto prozva Tabera, jer je Jahvin oganj ondje zaplamtio na njih."},{"v":4,"t":"Svjetinu koja se oko njih skupila obuzme pohlepa za jelom. Izraelci se opet upuste u jadikovanje govoreći: “Tko će nas nasititi mesom?"},{"v":5,"t":"Sjećamo se kako smo u Egiptu jeli badava ribe, krastavaca, dinje, prÓase, luka i češnjaka."},{"v":6,"t":"Sad nam život vene; nema ničega, osim mÓane, pred našim očima.”"},{"v":7,"t":"MÓana je bila kao zrno korijandera i nalik na bdelij."},{"v":8,"t":"Narod išao naokolo, skupljao je, a onda tro kamenom na kamenoj ploči ili stÓupao u stÓupi. Kuhao ju je u loncu i od nje pravio kolače. Okus joj bijaše kao okus kolača zgotovljena u ulju."},{"v":9,"t":"Kad bi se noću spuštala rosa po taborištu, s njome bi se spustila i mÓana."},{"v":10,"t":"Mojsije je slušao kako jadikuje narod u svojim obiteljima, svatko na ulazu u svoj šator. Gnjev Jahvin žestoko planu i Mojsije se ražalosti."},{"v":11,"t":"“Zašto zlostavljaš slugu svoga?” - upravi Mojsije riječ Jahvi. “Zašto nisam stekao milost u tvojim očima kad si na me uprtio teret svega ovog naroda?"},{"v":12,"t":"Zar je od mene potekao sav ovaj narod? Zar sam ga ja rodio, kad veliš: 'Nosi ga u svome krilu, kao što dojilja nosi dojenče, u zemlju što sam je pod zakletvom obećao njihovim očevima!'"},{"v":13,"t":"Odakle meni meso da ga dam svemu ovom puku koji plače oko mene govoreći: 'Daj nam mesa da jedemo!'"},{"v":14,"t":"Ja sam ne mogu nositi sav ovaj narod. Preteško je to za me."},{"v":15,"t":"Ako ćeš ovako sa mnom postupati, radije me ubij, ako sam stekao milost u tvojim očima, da više ne gledam svoga jada.”"},{"v":16,"t":"Onda Jahve reče Mojsiju: “Skupi mi sedamdeset muževa između starješina izraelskih za koje znaš da su starješine narodu i njegovi nadglednici. Dovedi ih u Šator sastanka pa neka ondje zauzmu svoja mjesta s tobom."},{"v":17,"t":"Ja ću sići i ondje s tobom govoriti; uzet ću nešto duha koji je na tebi i stavit ću ga na njih. Tako će s tobom nositi teret naroda da ga ne nosiš sam."},{"v":18,"t":"Nadalje, kaži narodu: Za sutra se posvetite i jest ćete mesa, jer ste mrmljali u uši Jahvi govoreći: 'Tko će nas nasititi mesa? U Egiptu nam je bilo dobro.' Jahve će vam, dakle, dati mesa da jedete."},{"v":19,"t":"Nećete ga jesti samo jedan dan, ni dva dana, ni pet dana, ni deset dana, ni dvadeset dana,"},{"v":20,"t":"nego cio mjesec, sve dok vam ne izbije na nosnice i ne ogadi vam se, jer ste odbacili Jahvu koji je među vama mrmljajući pred njim riječima: 'Zašto smo uopće odlazili iz Egipta!'”"},{"v":21,"t":"“Naroda u kojemu se nalazim”, odgovori Mojsije, “ima šest stotina tisuća pješaka, a ti kažeš: 'Mesa ću im dati da jedu mjesec dana.'"},{"v":22,"t":"Može li im se naklati sitne i krupne stoke da im dostane? Mogu li im se sve ribe iz mora zgrnuti da im bude dosta?”"},{"v":23,"t":"Jahve reče Mojsiju: “Zar je ruka Jahvina tako kratka? Sad ćeš vidjeti hoće li se obistiniti moja riječ ili neće.”"},{"v":24,"t":"Mojsije izađe i kaza narodu Jahvine riječi. Onda skupi sedamdeset muževa između narodnih starješina i smjesti ih oko Šatora."},{"v":25,"t":"Jahve siđe u oblaku i poče s njim govoriti. Zatim uze od duha koji bijaše na njemu i stavi na onu sedamdesetoricu starješina. Kad duh počinu na njima, počeše prorokovati, ali to više nikad ne učiniše."},{"v":26,"t":"Dvojica ostadoše u taboru. Jednome je bilo ime Eldad, a drugome Medad. Duh je i na njima počinuo - bili su i oni među upisanima, premda nisu došli u tabor - te počeše u taboru prorokovati."},{"v":27,"t":"Neki mladić otrča te javi Mojsiju: “Eldad i Medad”, reče, “prorokuju u taboru!”"},{"v":28,"t":"Jošua, sin Nunov, koji je posluživao Mojsija od svoje mladosti, prozbori i reče: “Mojsije, gospodaru moj, ušutkaj ih!”"},{"v":29,"t":"Mojsije mu odgovori: “Zar si zavidan zbog mene! Oh, kad bi sav narod Jahvin postao prorok! Kad bi Jahve na njih izlio svoga duha!”"},{"v":30,"t":"Potom se Mojsije i starješine izraelske vrate u tabor."},{"v":31,"t":"Tada Jahve zapovjedi te zapuhnu vjetar i nanese prepelice od mora i sasu ih na tabor, na dan hoda i s ove i s one strane tabora, na dva lakta iznad zemlje."},{"v":32,"t":"Narod je ustao te je toga cijeloga dana, svu noć i cio sutrašnji dan skupljao prepelice. Onaj tko ih je skupio najmanje imao je deset homera."},{"v":33,"t":"Zatim ih razastriješe oko tabora. Meso još bijaše među njihovim zubima - još ga nisu prožvakali - kadli planu Jahvin gnjev protiv naroda: Jahve udari narod strašnim pomorom."},{"v":34,"t":"Ono se mjesto prozva Kibrot Hataava, jer su ondje pokopali one koji se bijahu polakomili."},{"v":35,"t":"Iz Kibrot Hataave narod se zaputi u Haserot. I utabori se u Haserotu."}]},"12":{"hr":[{"v":1,"t":"A Mirjam i Aron uzeše rogoboriti protiv Mojsija zbog žene Kušanke kojom se oženio; jer bijaše uzeo za ženu jednu Kušanku."},{"v":2,"t":"“Zar je samo Mojsiju govorio Jahve?” - rekoše mu. “Zar i nama nije govorio?” Jahve to ču."},{"v":3,"t":"Mojsije je bio veoma skroman čovjek, najskromniji čovjek na zemlji."},{"v":4,"t":"I odmah reče Jahve Mojsiju, Aronu i Mirjami: “Vas se troje pojavite u Šatoru sastanka.” Njih se troje pojavi."},{"v":5,"t":"U stupu oblaka siđe Jahve te stade na ulazu u Šator. Zovnu Arona i Mirjamu. Kad njih dvoje istupi naprijed,"},{"v":6,"t":"reče Jahve: “Saslušajte riječi moje: Nađe li se među vama prorok, u viđenju njemu ja se javljam, u snu njemu progovaram."},{"v":7,"t":"Ali nije tako sa slugom mojim Mojsijem. Od svih u kući mojoj najvjerniji je on."},{"v":8,"t":"Iz usta u usta njemu ja govorim, očevidnošću, a ne zagonetkama, i lik Jahvin on smije gledati. Kako se onda niste bojali govoriti protiv sluge moga Mojsija?”"},{"v":9,"t":"Uskipjevši gnjevom na njih, Jahve ode."},{"v":10,"t":"Čim se od šatora oblak udaljio, gle! Mirjam ogubavi, kao snijegom posuta. Aron se okrenu prema Mirjami, a to guba na njoj."},{"v":11,"t":"Tada rekne Aron Mojsiju: “Gospodaru moj, ne svaljuj na nas kazne za grijeh koji smo u ludosti počinili i kojega smo krivci."},{"v":12,"t":"Ne daj da ona ostane kao mrtvo dijete kojemu je već na izlasku iz majčine utrobe meso napol uništeno!”"},{"v":13,"t":"Tada zavapi Mojsije Jahvi: “Bože, molim te, ozdravi je!”"},{"v":14,"t":"“Da joj je otac njezin pljunuo u lice”, reče Jahve Mojsiju, “zar se ne bi morala stidjeti sedam dana? Neka i ona bude odvojena izvan tabora sedam dana, pa neka se poslije opet pripusti.”"},{"v":15,"t":"Tako je Mirjam bila odvojena izvan tabora sedam dana. Narod nije na put polazio dok Mirjam nije opet bila pripuštena."},{"v":16,"t":"Poslije toga narod krenu iz Haserota i utabori se u pustinji Paranu."}]},"13":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Pošalji ljude, po jednoga čovjeka iz pojedinog pradjedovskog plemena, da izvide kanaansku zemlju, koju dajem Izraelcima. Pošaljite sve njihove glavare!”"},{"v":3,"t":"Na Jahvinu zapovijed Mojsije ih posla iz pustinje Parana. Svi ti ljudi bijahu glavari Izraelaca."},{"v":4,"t":"A ovo su njihova imena: Šamua, sin Zakurov, od plemena Rubenova;"},{"v":5,"t":"Šafat, sin Horijev, od plemena Šimunova;"},{"v":6,"t":"Kaleb, sin Jefuneov, od plemena Judina;"},{"v":7,"t":"Jigal, sin Josipov, od plemena Jisakarova;"},{"v":8,"t":"Hošea, sin Nunov, od plemena Efrajimova;"},{"v":9,"t":"Palti, sin Rafuov, od plemena Benjaminova;"},{"v":10,"t":"Gadiel, sin Sodijev, od plemena Zebulunova;"},{"v":11,"t":"Gadi, sin Susijev, od plemena Josipova, od plemena Manašeova;"},{"v":12,"t":"Amiel, sin Gemalijev, od plemena Danova;"},{"v":13,"t":"Setur, sin Mikaelov, od plemena Ašerova;"},{"v":14,"t":"Nahbi, sin Vofsijev, od plemena Naftalijeva;"},{"v":15,"t":"Geuel, sin Makijev, od plemena Gadova."},{"v":16,"t":"To su imena ljudi koje je Mojsije poslao da izvide zemlju. A Hošeu, sina Nunova, Mojsije prozva Jošuom."},{"v":17,"t":"Posla ih Mojsije da izvide kanaansku zemlju pa im reče: “Idite gore u Negeb, onda se popnite na brdo."},{"v":18,"t":"Razgledajte zemlju kakva je. Je li narod koji u njoj živi jak ili slab, malobrojan ili mnogobrojan?"},{"v":19,"t":"Kakva je zemlja u kojoj živi: dobra ili rđava? Kakvi su gradovi u kojima borave: otvoreni ili utvrđeni?"},{"v":20,"t":"Kakvo je tlo: plodno ili mršavo? Ima li po njemu drveća ili nema? Odvažni budite i ponesite plodova te zemlje.” Bilo je upravo vrijeme ranog grožđa."},{"v":21,"t":"Odu oni gore da izvide zemlju od pustinje Sina do Rehoba, koji je na ulazu u Hamat."},{"v":22,"t":"Popnu se u Negeb i dođu do Hebrona, gdje su se nalazili Ahiman, Šešaj i Talmaj, Anakovi potomci. - Hebron je osnovan sedam godina prije nego Soan u Egiptu. -"},{"v":23,"t":"Kada stigoše u Dolinu Eškol, odrezaše ondje lozu s grozdom i ponesoše ga, udvoje, na motki; ponesoše i mogranja i smokava."},{"v":24,"t":"Ono se mjesto prozva Dolina Eškol zbog grozda koji su ondje Izraelci odrezali."},{"v":25,"t":"Nakon četrdeset dana vrate se iz zemlje koju su izviđali."},{"v":26,"t":"Odu k Mojsiju i Aronu i svoj izraelskoj zajednici u Kadeš, u Paranskoj pustinji. Podnesu njima i svoj zajednici izvještaj, a onda im pokažu plodove zemlje."},{"v":27,"t":"Izvijeste ga oni: “Išli smo u zemlju u koju si nas poslao. Zaista njome teče med i mlijeko. Evo njezinih plodova."},{"v":28,"t":"Ali je jak narod koji u onoj zemlji živi, gradovi su utvrđeni i vrlo veliki. A vidjesmo ondje i potomke Anakove."},{"v":29,"t":"Amalečani borave u negepskom kraju: Hetiti, Jebusejci i Amorejci žive u brdu; a Kanaanci se nalaze uz more i duž Jordana.”"},{"v":30,"t":"Kaleb ušutka narod oko Mojsija i progovori: “Krenimo ne oklijevajući i zauzmimo je, jer je možemo nadvladati!”"},{"v":31,"t":"Ali ljudi što su s njim išli odvratiše: “Ne možemo ići na onaj narod jer je jači od nas.”"},{"v":32,"t":"I počnu ozloglašivati Izraelcima zemlju koju su izviđali: “Zemlja kroz koju smo prošli da je izvidimo zemlja je što proždire svoje stanovništvo. Sav narod što ga u njoj vidjesmo ljudi su krupna stasa."},{"v":33,"t":"Vidjesmo ondje i divove - Anakovo potomstvo od divova. Činilo nam se da smo prema njima kao skakavci. Takvi bijasmo i njima.”"}]},"14":{"hr":[{"v":1,"t":"Tada zagraja sva zajednica i poče vikati. I te noći narod plakaše."},{"v":2,"t":"Svi su Izraelci mrmljali protiv Mojsija i Arona. Sva im je zajednica govorila: “Kamo sreće da smo pomrli u zemlji egipatskoj! Ili da smo pomrli u ovoj pustinji!"},{"v":3,"t":"Zašto nas Jahve vodi u tu zemlju da padnemo od mača a žene naše i djeca da postanu roblje! Zar nam ne bi bilo bolje da se vratimo u Egipat!”"},{"v":4,"t":"Jedan je drugome govorio: “Postavimo sebi vođu i vratimo se u Egipat!”"},{"v":5,"t":"Mojsije i Aron padoše ničice pred svom okupljenom izraelskom zajednicom."},{"v":6,"t":"A Jošua, sin Nunov, i Kaleb, sin Jefuneov, koji bijahu među onima što su izviđali zemlju, razderaše svoju odjeću."},{"v":7,"t":"Zatim rekoše svoj zajednici izraelskoj: “Zemlja kroz koju smo prošli da je istražimo izvanredno je dobra."},{"v":8,"t":"Ako nam Jahve bude dobrostiv, u tu će nas zemlju dovesti i dat će nam je. To je zemlja u kojoj teče med i mlijeko."},{"v":9,"t":"Samo, nemojte se buniti protiv Jahve! Ne bojte se naroda one zemlje: tÓa on je zalogaj za nas. Oni su bez zaštite, a s nama je Jahve! Ne bojte ih se!”"},{"v":10,"t":"I dok je sva zajednica već mislila da ih kamenuje, pokaza se Slava Jahvina u Šatoru sastanka svima sinovima Izraelovim."},{"v":11,"t":"Tada reče Mojsiju: “Dokle će me taj narod prezirati? Dokle mi neće vjerovati unatoč svim znamenjima što sam ih među njima izvodio?"},{"v":12,"t":"Udarit ću ih pomorom i istrijebiti, a od tebe ću učiniti narod veći i moćniji od njega.”"},{"v":13,"t":"Onda Mojsije reče Jahvi: “Egipćani su shvatili da si ti, svojom moći, izveo ovaj narod između njih."},{"v":14,"t":"Oni su to kazali žiteljima one zemlje. Već su saznali da si ti, Jahve, usred ovog naroda, kojemu se očituješ licem u lice, i da ti, Jahve, u oblaku stojiš nad njima; da obdan u stupu od oblaka, a obnoć u stupu od ognja ideš pred njima."},{"v":15,"t":"Zato, ako pobiješ ovaj narod kao jednoga čovjeka, narodi koji su čuli glas o tebi reći će:"},{"v":16,"t":"'Jahve je bio nemoćan da dovede ovaj narod u zemlju koju mu je pod zakletvom obećao, i zato ih je poubijao u pustinji.'"},{"v":17,"t":"Zato neka se snaga moga Gospodina uzvisi, kako si najavio rekavši:"},{"v":18,"t":"'Jahve je spor na srdžbu, a bogat milosrđem; podnosi opačinu i prijestup, ali krivca ne ostavlja nekažnjena, nego opačinu otaca kažnjava na djeci do trećega i četvrtog koljena.'"},{"v":19,"t":"Oprosti krivnju ovome narodu po veličini svoga milosrđa, kao što si vodio ovaj narod od Egipta dovde.”"},{"v":20,"t":"“Opraštam po riječi tvojoj”, reče Jahve."},{"v":21,"t":"“Ali ipak, tako ja živ bio i slave se Jahvine napunila sva zemlja,"},{"v":22,"t":"ni jedan od ljudi koji su vidjeli slavu moju i znamenja što sam ih izveo u Egiptu i u pustinji, pa me ipak iskušavali već deset puta ne hoteći poslušati moj glas,"},{"v":23,"t":"neće vidjeti zemlje što sam je pod zakletvom obećao njihovim ocima; nitko od onih koji me preziru neće je vidjeti."},{"v":24,"t":"A slugu svoga Kaleba, jer je u njemu drukčiji duh i jer mi bijaše poslušan, njega ću ja dovesti u zemlju u koju je išao i njegovi će je potomci zaposjesti! Neka Amalečani i Kanaanci samo ostanu u dolini."},{"v":25,"t":"Sutra se vratite i krenite u pustinju put Crvenog mora.”"},{"v":26,"t":"Još reče Jahve Mojsiju i Aronu:"},{"v":27,"t":"“Dokle će ta opaka zajednica mrmljati protiv mene? Čuo sam tužbe što ih Izraelci na me dižu."},{"v":28,"t":"Kaži im: Tako ja živ bio, objavljuje Jahve, kako ste na moje uši govorili, tako ću vam i učiniti."},{"v":29,"t":"U ovoj pustinji popadat će vaša mrtva tijela: svih vas koji ste ubilježeni u bilo koji vaš popis od dvadeset godina pa naprijed, koji ste rogoborili protiv mene."},{"v":30,"t":"Nećete ući u zemlju na koju sam svoju ruku digao da vas u njoj nastanim, osim Kaleba, sina Jefuneova, i Jošue, sina Nunova."},{"v":31,"t":"A vašu djecu, o kojoj kažete da bi postala roblje, njih ću uvesti da nastane zemlju što ste je vi prezreli."},{"v":32,"t":"A vi? Neka vam tjelesa popadaju u ovoj pustinji!"},{"v":33,"t":"Vaši sinovi neka lutaju pustinjom četrdeset godina, neka trpe zbog vaše nevjere dok vam ne ispropadaju tjelesa u ovoj pustinji."},{"v":34,"t":"Prema broju dana u koje ste istraživali zemlju - dana četrdeset, za svaki dan jednu godinu - ispaštajte svoje opačine četrdeset godina. Iskusite što znači mene napustiti."},{"v":35,"t":"Ja, Jahve, to kažem: tako ću postupiti s ovom opakom zajednicom što se sjatila protiv mene. U ovoj istoj pustinji neka završi! Tu neka izgine.”"},{"v":36,"t":"A oni ljudi koje Mojsije bijaše poslao da istraže zemlju i koji su nakon povratka potakli svu zajednicu da rogobori protiv njega ozloglašujući zemlju;"},{"v":37,"t":"oni, dakle, ljudi koji su zlobno ozloglasili zemlju bijahu pomoreni pred Jahvom."},{"v":38,"t":"Od onih ljudi koji su išli da istraže zemlju ostadoše na životu jedino Jošua, sin Nunov, i Kaleb, sin Jefuneov."},{"v":39,"t":"Kad je Mojsije prenio te riječi svim Izraelcima, narod se uvelike ražalosti."},{"v":40,"t":"I uranivši ujutro počnu se uspinjati na vrh brda govoreći. “Evo uzlazimo na mjesto o kojem je govorio Jahve jer smo zgriješili.”"},{"v":41,"t":"A Mojsije rekne: “Zašto kršite zapovijed Jahvinu? Nećete uspjeti."},{"v":42,"t":"Ne penjite se, da vas ne potuku vaši neprijatelji, jer Jahve nije među vama."},{"v":43,"t":"Ta ondje se pred vama nalaze Amalečani i Kanaanci te ćete od mača pasti jer ste se odvratili od Jahve i jer Jahve neće biti s vama.”"},{"v":44,"t":"Ali se oni prkosno penjahu prema vrhu brda, iako se ni Kovčeg saveza Jahvina ni Mojsije nisu micali iz tabora."},{"v":45,"t":"Amalečani i Kanaanci koji su živjeli na onome brdu spuste se, udare po njima i rasprše ih sve do Horme."}]},"15":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Govori Izraelcima i reci im: 'Kad uđete u zemlju gdje ćete boraviti i koju vam ja dajem,"},{"v":3,"t":"pa budete prinosili Jahvi paljenu žrtvu, paljenicu ili klanicu, zavjetnicu ili dragovoljnu žrtvu, ili žrtvu prigodom svojih svetkovina - praveći tako od krupne ili sitne stoke ugodan miris Jahvi -"},{"v":4,"t":"neka prinositelj prinese svoj dar Jahvi: prinosnicu od desetine efe najboljeg brašna, zamiješena u četvrtini hina ulja."},{"v":5,"t":"Uz paljenicu ili uz klanicu prinesi čevrtinu hina vina za ljevanicu na svako janje."},{"v":6,"t":"Povrh ovna prinesi kao prinosnicu dvije desetine efe najboljeg brašna, zamiješena u jednoj trećini hina ulja;"},{"v":7,"t":"i vina za ljevanicu prinesi trećinu hina na ugodan miris Jahvi."},{"v":8,"t":"Ako Jahvi prinosiš junca kao paljenicu ili kao klanicu da izvršiš zavjet ili kao pričesnicu,"},{"v":9,"t":"neka se onda uz junca prinesu tri desetine efe najboljeg brašna, zamiješena u pola hina ulja,"},{"v":10,"t":"a za ljevanicu prinesi pola hina vina kao paljenu žrtvu na ugodan miris Jahvi."},{"v":11,"t":"Neka se tako postupi uza svakoga vola i uza svakoga ovna, uza svaku glavu sitne stoke, ovce ili koze:"},{"v":12,"t":"koliko ih god prinesete, za svako pojedino tako učinite, već prema njihovu broju."},{"v":13,"t":"Svaki domorodac neka postupa ovako kad prinosi žrtvu paljenu na ugodan miris Jahvi."},{"v":14,"t":"I ako koji stranac koji živi među vama, ili će biti među vašim potomcima, htjedne prinijeti žrtvu paljenu na ugodan miris Jahvi, neka radi kako i vi radite."},{"v":15,"t":"Neka je jedan zakon i za vas i za stranca koji s vama boravi. To je trajan zakon za vaše naraštaje: pred Jahvom, kako je s vama, tako neka bude i sa strancem."},{"v":16,"t":"Jedan zakon i jedno pravo neka vrijedi za vas i za stranca koji s vama boravi.'”"},{"v":17,"t":"Jahve reče Mojsiju:"},{"v":18,"t":"“Govori Izraelcima i reci im: 'Kad dođete u zemlju u koju vas vodim"},{"v":19,"t":"i budete jeli kruh te zemlje, prinesite podizanicu Jahvi."},{"v":20,"t":"Kao prvinu iz svojih naćava prinesite jedan kolač kao podizanicu; prinesite ga kao i podizanicu s gumna."},{"v":21,"t":"Od prvine svojih naćava davajte Jahvi podizanicu od naraštaja do naraštaja.'”"},{"v":22,"t":"“Ako nehotice pogriješite te ne budete obdržavali koju od zapovijedi što ih je Jahve objavio po Mojsiju -"},{"v":23,"t":"sve što vam je Jahve zapovjedio po Mojsiju, odonda kad vam je izdao zapovijedi pa dalje od koljena do koljena -"},{"v":24,"t":"onda: ako je to počinjeno nepažnjom zajednice, neka sva zajednica prinese jednoga junca kao paljenicu na ugodan miris Jahvi s propisanom prikaznicom i ljevanicom i jednoga jarca kao okajnicu."},{"v":25,"t":"Neka svećenik obavi obred pomirenja nad svom izraelskom zajednicom, pa će im biti oprošteno. Bila je samo nepažnja, a oni su prinijeli svoj dar - paljenu žrtvu Jahvi - i okajnicu pred Jahvom za svoju nepažnju."},{"v":26,"t":"Bit će oprošteno svoj izraelskoj zajednici, a tako i strancu koji među njima boravi, jer se sav narod iz nepažnje ogriješio."},{"v":27,"t":"Pogriješi li iz nepažnje pojedinac, neka prinese jedno žensko kozle od godine dana kao okajnicu."},{"v":28,"t":"Neka svećenik obavi obred pomirenja pred Jahvom nad osobom koja je nehotice pogriješila od nepažnje. Kad nad njom obavi obred pomirenja, bit će joj oprošteno."},{"v":29,"t":"Kada tko pogriješi nepažnjom, neka vam jedan zakon vrijedi i za domoroca i za stranca koji boravi među vama."},{"v":30,"t":"Ali onaj koji nešto učini naumice, bio on domorodac ili stranac, taj na Jahvu huli. Takav neka se istrijebi između svoga naroda"},{"v":31,"t":"jer je prezreo Jahvinu riječ i prekršio njegovu zapovijed. Neka se takav iskorijeni. Neka njegova krivnja padne na nj!”"},{"v":32,"t":"Kad su Izraelci bili u pustinji, nađu čovjeka kako kupi drva u subotnji dan."},{"v":33,"t":"I oni koji su ga našli da kupi drva dovedu ga Mojsiju i Aronu i svoj zajednici."},{"v":34,"t":"Stave ga pod stražu, jer još nije bilo određeno što treba s njim učiniti."},{"v":35,"t":"“Toga čovjeka treba pogubiti!” - reče Jahve Mojsiju. “Neka ga kamenjem zaspe izvan tabora sva zajednica.”"},{"v":36,"t":"Sva ga zajednica izvede izvan tabora i zasu ga kamenjem te on poginu, kako je Jahve zapovjedio Mojsiju."},{"v":37,"t":"Reče Jahve Mojsiju:"},{"v":38,"t":"“Govori Izraelcima i reci im: neka od naraštaja do naraštaja prave rese na skutovima svojih haljina, a za resu svakoga skuta neka privezuju ljubičastu vrpcu."},{"v":39,"t":"Imat ćete rese zato da vas pogled na njih sjeća svih Jahvinih zapovijedi. Vršite ih, a ne zanosite se svojim srcem i svojim očima, što vas tako lako zavode na bludnost."},{"v":40,"t":"Tako ćete se sjećati svih mojih zapovijedi, vršit ćete ih i bit ćete posvećeni svome Bogu."},{"v":41,"t":"Ja sam Jahve, Bog vaš, koji sam vas izveo iz zemlje egipatske da vam budem Bogom. Ja, Jahve, Bog vaš.”"}]},"16":{"hr":[{"v":1,"t":"Korah, sin Jisharov, sin Kehatov, sin Levijev, pa Datan i Abiram, sinovi Eliabovi, i On, sin Peletov - potomci Rubenovi -"},{"v":2,"t":"ustanu protiv Mojsija zajedno sa dvjesta pedeset Izraelaca, glavara zajednice, uglednih na skupštini i ljudi na glasu."},{"v":3,"t":"Oni se sjate oko Mojsija i Arona govoreći im: “Vi prelazite mjeru! Sva je zajednica, svi njezini članovi, posvećena i među njima je Jahve. Zašto se onda uzvisujete iznad zajednice Jahvine!”"},{"v":4,"t":"Kad to ču Mojsije, pade ničice."},{"v":5,"t":"Zatim reče Korahu i svoj njegovoj družini: “Sutra će Jahve pokazati tko je njegov i tko je posvećen, kome dopušta da mu se približi. Koga sebi izabere, k sebi će ga i pustiti."},{"v":6,"t":"Učinite ovo: uzmite kadionike, Korah i sva njegova družina;"},{"v":7,"t":"sutra stavite u njih vatre i metnite odozgo tamjana pred Jahvom. Koga Jahve odabere, taj neka bude posvećen. Vi prelazite mjeru, Levijevci!”"},{"v":8,"t":"Potom Mojsije reče Korahu: “Poslušajte, Levijevci!"},{"v":9,"t":"Zar vam je malo što vas je Bog Izraelov izdvojio iz Izraelove zajednice da vas približi k sebi te da vršite službu u Jahvinu prebivalištu i da stojite pred zajednicom služeći joj?"},{"v":10,"t":"Promaknuo je tebe i s tobom svu tvoju braću Levijevce, a vi još tražite i svećeništvo!"},{"v":11,"t":"Ti i sva tvoja družina, dakle, sjatili ste se protiv Jahve; jer što je Aron da protiv njega rogoborite?”"},{"v":12,"t":"Zatim posla Mojsije po Datana i Abirama, sinove Eliabove, ali oni odgovore: “Nećemo doći!"},{"v":13,"t":"Zar je malo što si nas odveo iz zemlje kojom teče med i mlijeko da nas pobiješ u ovoj pustinji, pa hoćeš da nasilno zagospodariš nad nama?"},{"v":14,"t":"Nisi nas uveo u zemlju kojom teče med i mlijeko i nisi nam dao u posjed njive i vinograde! Misliš li iskopati oči ovim ljudima? Nećemo doći!”"},{"v":15,"t":"Mojsije se vrlo razljuti i reče Jahvi: “Ne obaziri se na njihovu prinosnicu! Ni jednoga njihova magarca nisam prisvojio niti sam ijednoga od njih oštetio.”"},{"v":16,"t":"Zatim Mojsije reče Korahu: “Ti i sva tvoja družina stupite sutra pred Jahvu; ti, i oni, i Aron."},{"v":17,"t":"Neka svaki uzme svoj kadionik, stavi u nj tamjana i neka svaki donese svoj kadionik pred Jahvu - dvjesta i pedeset kadionika. A i ti i Aron donesite svaki svoj kadionik.”"},{"v":18,"t":"Svaki uzme svoj kadionik, stavi u nj vatre, onda odozgo metne tamjana i stane s Mojsijem i Aronom kod ulaza u Šator sastanka."},{"v":19,"t":"Kad, naprama njima, sabra Korah svu zajednicu na ulazu u Šator sastanka, onda se svoj zajednici pokaza slava Jahvina."},{"v":20,"t":"I reče Jahve Mojsiju i Aronu:"},{"v":21,"t":"“Odvojite se od te zajednice da je odmah satrem!”"},{"v":22,"t":"Oni popadoše ničice i povikaše: “Bože! Bože životnog duha u svakome tijelu! Zar ćeš se razgnjeviti na svu zajednicu kad je samo jedan sagriješio!”"},{"v":23,"t":"Onda Jahve reče Mojsiju:"},{"v":24,"t":"“Reci toj zajednici: 'Uklonite se iz okolice prebivališta Koraha, Datana i Abirama!'”"},{"v":25,"t":"Mojsije ustade i pođe k Datanu i Abiramu. Za njim krenuše izraelske starješine."},{"v":26,"t":"Zatim ovako progovori zajednici: “Odstupite od šatora tih opakih ljudi! Ne dotičite se ničega što je njihovo, da ne budete uništeni zbog svih njihovih grijeha.”"},{"v":27,"t":"Tako se oni udalje iz okolice prebivališta Korahova, Datanova i Abiramova. Uto izađu Datan i Abiram te stanu na ulazu svojih šatora sa svojim ženama, svojim sinovima i svojom nejačadi."},{"v":28,"t":"“Po ovom ćete vidjeti”, reče Mojsije, “da me Jahve poslao da vršim sva ova djela, a da ih ne činim sam od sebe:"},{"v":29,"t":"ako ovi ljudi umru kao što umru i svi ljudi; ako ih pohodi sudbina kakva pohodi sve ljude, onda me Jahve nije poslao."},{"v":30,"t":"Ali ako Jahve učini nečuveno: ako zemlja rastvori svoje ralje i proguta ih sa svim što je njihovo te živi siđu u Šeol, onda znajte da su ovi ljudi prezreli Jahvu.”"},{"v":31,"t":"A kad on završi sve te riječi, tlo se pod njima raspukne;"},{"v":32,"t":"zemlja rastvori svoje ralje i proguta ih s njihovim domovima, sa svim Korahovim ljudima i svim njihovim imanjem."},{"v":33,"t":"Živi siđu u Šeol, oni i sve njihovo. Onda se nad njima zemlja zatvori i oni iščeznu iz zbora."},{"v":34,"t":"Na njihov vrisak svi Izraelci što su stajali oko njih pobjegoše govoreći: “Da i nas zemlja ne proguta!”"},{"v":35,"t":"Ali sukne oganj od Jahve te proždre dvjesta i pedeset ljudi koji su prinosili tamjan."}]},"17":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Kaži Eleazaru, sinu svećenika Arona, da ukloni kadionike - jer su posvećeni - iz toga zgarišta, a neposvećenu vatru iz njih neka razaspe podalje."},{"v":3,"t":"Kadionici onih koji su sagriješili i grijehom život pokopali neka se prekuju u pločice za oblaganje žrtvenika. Doneseni su, naime, pred Jahvu, pa su posvećeni. Neka budu opomenom Izraelcima!”"},{"v":4,"t":"Tako svećenik Eleazar uze kadionike od tuča što su ih prinosili oni koji izgorješe; prekovaše ih u pločice za oblaganje žrtvenika."},{"v":5,"t":"One su opomena Izraelcima da se nitko nepozvan - nitko tko nije od Aronova potomstva - ne smije približiti da pali tamjan pred Jahvom, kako mu se ne bi dogodilo kao Korahu i njegovoj družini, prema onom što je kazao Jahve po Mojsiju."},{"v":6,"t":"Sutradan je sva zajednica rogoborila protiv Mojsija i Arona. “Pobili ste Jahvin narod!” - govorili su."},{"v":7,"t":"Dok se zajednica skupljala protiv Mojsija i Arona, oni se okrenuše prema Šatoru sastanka, i gle! oblak ga prekri i slava se Jahvina pokaza."},{"v":8,"t":"Tada Mojsije i Aron odoše pred Šator sastanka."},{"v":9,"t":"I Jahve reče Mojsiju:"},{"v":10,"t":"“Udaljite se od te zajednice; u tili ću je čas uništiti!” Oni padoše ničice."},{"v":11,"t":"Zatim Mojsije reče Aronu: “Uzmi kadionik, stavi u nj vatre sa žrtvenika, metni tamjana, a onda se žuri do zajednice da obaviš nad njom obred pomirenja. Gnjev je Jahvin već izbio i zlo je počelo!”"},{"v":12,"t":"Aron uze što mu je Mojsije rekao te otrča usred zbora, a kad tamo: pomor među narodom već počeo. Stavi tamjana te obavi obred pomirenja nad narodom."},{"v":13,"t":"Zatim stade između mrtvih i živih i zlo se ustavi."},{"v":14,"t":"Bilo ih je mrtvih od toga zla četrnaest tisuća i sedam stotina, osim onih koji su poginuli zbog Koraha."},{"v":15,"t":"Aron se vrati k Mojsiju na ulaz u Šator sastanka: pomor se ustavi."},{"v":16,"t":"Jahve reče Mojsiju:"},{"v":17,"t":"“Razloži Izraelcima te od njih uzmi po jedan štap za svaki predjedovski dom; uzmi od svih njihovih starješina za njihove pradjedovske domove dvanaest štapova. Ime svakoga napiši na njegovu štapu."},{"v":18,"t":"A kako ima po jedan štap za svakoga starješinu pradjedovskih domova, Aronovo ime napiši na Levijevu štapu."},{"v":19,"t":"Onda ih pohrani u Šator sastanka pred Svjedočanstvo; ondje gdje se s tobom sastajem."},{"v":20,"t":"Štap onoga čovjeka koga izaberem propupat će. Tako ću maknuti od sebe rogoborenje Izraelaca kojim prigovaraju vama.”"},{"v":21,"t":"Mojsije tako kaza Izraelcima. Sve njihove starješine dadoše mu štap, po jedan štap za svakoga starješinu - dakle, dvanaest štapova za njihove pradjedovske domove. Među njihovim štapovima bio je i štap Aronov."},{"v":22,"t":"Mojsije pohrani štapove pred Jahvu u Šatoru svjedočanstva."},{"v":23,"t":"Kad sutradan Mojsije uđe u Šator svjedočanstva, gle: štap Arona iz doma Levijeva propupao! Potjerala mladica, procvjetao cvijet i sazreli bademi."},{"v":24,"t":"Tada iznese Mojsije ispred Jahve sve štapove sinovima Izraelovim. Oni ih razgledaše, a onda svatko uze svoj štap."},{"v":25,"t":"Jahve reče Mojsiju: “Opet stavi Aronov štap pred Svjedočanstvo, neka se čuva za znak buntovnim sinovima. Dokončaj tako njihovo rogoborenje protiv mene da ne izginu.”"},{"v":26,"t":"I učini Mojsije: kako mu je Jahve zapovjedio, tako učini."},{"v":27,"t":"“Izgibosmo!” - rekoše Izraelci Mojsiju. “Propadosmo! Svi odreda propadosmo!"},{"v":28,"t":"Tko god priđe Jahvinu prebivalištu, umire ... Zar ćemo svi izginuti?”"}]},"18":{"hr":[{"v":1,"t":"Tada Jahve reče Aronu: “Ti, tvoji sinovi i tvoj pradjedovski dom s tobom bit ćete odgovorni za grijehe u Svetištu; ti i tvoji sinovi s tobom bit ćete odgovorni za grijehe svoga svećeništva."},{"v":2,"t":"Pridruži k sebi i svoju braću od Levijeva plemena - tvoga pradjedovskog doma - neka ti se priključe da ti poslužuju, tebi i tvojim sinovima s tobom, pred Šatorom svjedočanstva."},{"v":3,"t":"Neka stoje na službu tebi i svemu Šatoru, ali neka se ne približuju pokućstvu u Svetištu niti žrtveniku, da ne poginu i oni i vi."},{"v":4,"t":"Neka su, dakle, tebi pridruženi i neka preuzmu brigu za Šator sastanka, svaku službu oko Šatora. I neka se ni jedan svjetovnjak ne približuje vama,"},{"v":5,"t":"a vi vršite službu u Svetištu i službu oko žrtvenika da se više ne izlijeva gnjev na Izraelce."},{"v":6,"t":"Uzeh, evo, vašu braću levite između Izraelaca vama za dar; kao darovani pripadaju Jahvi da obavljaju službu oko Šatora sastanka."},{"v":7,"t":"Ti i tvoji sinovi s tobom preuzmite svećeničke poslove oko svega što spada na žrtvenik i iza zavjese. Službu koju dajem na dar vašem svećeništvu vi obavljajte. A svjetovnjak koji se primakne neka se pogubi.”"},{"v":8,"t":"Još reče Jahve Aronu: “Tebi, evo, povjeravam brigu o onom što se meni prinosi. Sve što Izraelci posvećuju dodjeljujem tebi i tvojim sinovima kao baštinu trajnim zakonom."},{"v":9,"t":"Ovo neka pripadne tebi od svetinja nad svetinjama: od paljenih žrtava svi njihovi darovi, za sve njihove prinosnice, za sve njihove okajnice i za sve njihove naknadnice što ih budu meni uzvraćali; ta vrlo sveta stvar neka pripadne tebi i tvojim sinovima!"},{"v":10,"t":"Blagujte ih kao najveće svetinje! Svaki muškarac može ih jesti. Neka ti budu svete!"},{"v":11,"t":"I ovo neka bude za te: ono što se uzima od izraelskih prinosa da se prinese kao prikaznica - trajnim zakonom predajem tebi, tvojim sinovima i tvojim kćerima s tobom. Svatko tko u tvome domu bude čist može od toga jesti."},{"v":12,"t":"Najbolje od novoga ulja i najbolje od novoga vina i žita - prvine koje se prinose Jahvi - predajem tebi."},{"v":13,"t":"Prvi rodovi svega u njihovoj zemlji što ih budu donosili Jahvi neka budu tvoji. Tko je god čist u tvome domu može ih jesti."},{"v":14,"t":"Sve što u Izraelu bude određeno za 'herem' neka je tvoje."},{"v":15,"t":"Svako prvorođenče svih bića - kako ljudi tako i životinja - što se prinose Jahvi neka bude tvoje. Samo pusti da se otkupi prvenac od ljudi i prvenče od nečiste stoke."},{"v":16,"t":"Kad budu stari mjesec dana, pusti da ih otkupljuju. A njihovu otkupnu cijenu odredi: pet srebrnih šekela, prema hramskom šekelu, a to je dvadeset gera."},{"v":17,"t":"Ali prvenče kravlje, prvenče ovčje i prvenče kozje neka se ne otkupljuje. Oni su svetinja. Krv njihovu izlij na žrtvenik, a pretilinu njihovu sažeži u kad kao žrtvu spaljenu na ugodan miris Jahvi."},{"v":18,"t":"Njihovo meso neka pripadne tebi; kao i grudi žrtve prikaznice i desno pleće."},{"v":19,"t":"Sve posvećene prinose što ih Izraelci podižu Jahvi predajem trajnim zakonom tebi, tvojim sinovima i tvojim kćerima s tobom. To je savez osoljen, trajan pred Jahvom, tebi i tvome potomstvu s tobom.”"},{"v":20,"t":"“Nemoj imati baštine u zemlji njihovoj”, reče Jahve Aronu, “niti sebi stječi posjeda među njima! Ja sam tvoj dio i tvoja baština među Izraelcima.”"},{"v":21,"t":"“Levijevim sinovima, evo, predajem u baštinu sve desetine u Izraelu za njihovu službu - za službu što je obavljaju u Šatoru sastanka."},{"v":22,"t":"A Izraelci neka se više ne primiču Šatoru sastanka, da ne navuku na se grijeh i ne poginu."},{"v":23,"t":"Neka samo leviti obavljaju službu u Šatoru sastanka; i neka oni budu odgovorni za svoj grijeh. Trajna je to odredba za vaše naraštaje; među Izraelcima neka nemaju posjeda,"},{"v":24,"t":"jer ja im predajem u posjed desetine što ih Izraelci prinose na dar Jahvi. Stoga sam za njih rekao: neka oni nemaju posjeda među Izraelcima.”"},{"v":25,"t":"Jahve reče Mojsiju:"},{"v":26,"t":"“Levitima govori i reci im: 'Kad od Izraelaca primate desetinu, koju ja od njih dajem vama u baštinu, od toga onda vi prinesite podizanicu Jahvi: desetinu od desetine."},{"v":27,"t":"Prinos će vam biti zaračunan kao da je prinos s gumna i Óotoka iz badnja."},{"v":28,"t":"Tako isto prinosite podizanicu Jahvi i od svih svojih desetina što ih primate od Izraelaca. Od toga davajte podizanicu Jahvinu svećeniku Aronu."},{"v":29,"t":"Od svih darova koje budete primali podižite podizanicu Jahvi; od svega ono najbolje - onaj dio koji treba posvećivati.'"},{"v":30,"t":"Još im reci: 'Pošto od toga prinesete najbolji dio, neka se to levitima uračuna kao prihod s gumna i prihod iz badnja."},{"v":31,"t":"Na svakome ga mjestu možete jesti, i vi i vaši ukućani, jer to vam je nagrada za vašu službu u Šatoru sastanka."},{"v":32,"t":"Pošto prinesete njegov najbolji dio, nećete navući na se grijeha; svetinja Izraelaca nećete oskvrnjivati te nećete ginuti.'”"}]},"19":{"hr":[{"v":1,"t":"Jahve reče Mojsiju i Aronu:"},{"v":2,"t":"“Ovo je zakonska odredba što ju je Jahve naredio: Reci Izraelcima neka ti dovedu crvenu junicu, zdravu, na kojoj nema mane i na koju još nije stavljan jaram."},{"v":3,"t":"A vi je predajte svećeniku Eleazaru. Neka se zatim izvede izvan tabora i zakolje pred njim."},{"v":4,"t":"Svećenik Eleazar neka uzme njezine krvi na svoj prst pa njome poškropi sedam puta prema pročelju Šatora sastanka."},{"v":5,"t":"Neka se onda junica spali na njegove oči; neka joj se spale: koža, meso, krv i nečist."},{"v":6,"t":"Potom neka svećenik uzme cedrovine, izopa i crvenoga prediva pa ih baci usred vatre gdje se krava spaljuje."},{"v":7,"t":"Neka svećenik opere svoju odjeću, a svoje tijelo u vodi okupa. Poslije toga neka se svećenik vrati u tabor, ali neka je nečist do večeri."},{"v":8,"t":"I onaj koji ju je spaljivao neka svoju odjeću opere i okupa svoje tijelo u vodi te bude nečist do večeri."},{"v":9,"t":"A jedan čist čovjek neka pokupi pepeo od junice pa ga pohrani izvan tabora na čisto mjesto da se čuva izraelskoj zajednici za vodu očišćenja. To je žrtva okajnica."},{"v":10,"t":"I onaj koji skupi pepeo od junice neka opere svoju odjeću i bude nečist do večeri. Neka to bude trajan zakon i za Izraelce i za stranca koji među njima boravi.”"},{"v":11,"t":"“Tko se dotakne mrtva ljudskog tijela neka je nečist sedam dana."},{"v":12,"t":"Takav neka se opere tom vodom trećega dana i sedmoga dana pa će biti čist. Ako se ne opere trećega dana i sedmoga dana, neće biti čist."},{"v":13,"t":"Tko se dotakne mrtvaca, tijela preminula čovjeka, a ne opere se, oskvrnjuje Jahvino prebivalište. Takav neka se iskorijeni iz Izraela. Budući da vodom za očišćenje nije bio poliven, nečist je; njegova je nečistoća još na njemu.”"},{"v":14,"t":"“Ovo je zakon kad koji čovjek umre u šatoru; tko god uđe u šator i tko god bude u šatoru neka je nečist sedam dana."},{"v":15,"t":"Svaka otvorena posuda koja ne bude zatvorena poklopcem neka je nečista."},{"v":16,"t":"A na otvorenu polju tko se god dotakne poginuloga od mača, ili mrtvaca, ili ljudskih kostiju, ili groba neka je nečist sedam dana."},{"v":17,"t":"Neka se za onoga koji se onečistio uzme pepela od životinje spaljene za okajnicu i na nj, u kakvu sudu, nalije žive vode."},{"v":18,"t":"Onda neka čist čovjek uzme izopa, zamoči ga u vodu te poškropi po šatoru, po svemu posuđu, po ljudima koji su tu bili, po onome koji se dotakao kostiju, ili ubijenoga, ili preminuloga, ili groba."},{"v":19,"t":"Neka čisti čovjek škropi nečistoga trećega i sedmoga dana. Tako će ga na sedmi dan očistiti. Taj onda neka opere svoju odjeću, okupa se u vodi i neka je navečer čist."},{"v":20,"t":"A bude li tko nečist pa se ne očisti, neka se iskorijeni iz zajednice, jer je oskvrnuo Jahvino svetište; vodom za očišćenje nije bio poliven; nečist je!"},{"v":21,"t":"Neka im i ovo bude trajnim zakonom: i onaj koji je škropio vodom za očišćenje neka opere svoju odjeću; i onaj koji je dirnuo vodu za očišćenje neka je nečist do večeri."},{"v":22,"t":"Čega se god nečisti dotakne neka je nečisto; a osoba koja se njega dotakne neka je nečista do večeri.”"}]},"20":{"hr":[{"v":1,"t":"Potom stigoše Izraelci, sva zajednica, u pustinju Sin u prvome mjesecu. Narod se nastani u Kadešu. Ondje umrije Mirjam i ondje je sahraniše."},{"v":2,"t":"Nije bilo vode za zajednicu. Stoga se udruže protiv Mojsija i protiv Arona."},{"v":3,"t":"Narod se poče svađati s Mojsijem i govoriti: “Da smo bar izginuli kad su nam i braća poginula pred Jahvom!"},{"v":4,"t":"Zašto ste doveli Jahvinu zajednicu u ovu pustinju da ovdje pomremo i mi i naša stoka?"},{"v":5,"t":"Zašto ste nas izveli iz Egipta da nas dovedete u ovo nesretno mjesto; mjesto u kojem nema ni žita, ni smokava, ni loze, ni mogranja? Nema ni vode da pijemo.”"},{"v":6,"t":"Mojsije i Aron odu ispred zajednice do ulaza u Šator sastanka i padnu ničice. Tada im se pokaza slava Jahvina."},{"v":7,"t":"I Jahve reče Mojsiju:"},{"v":8,"t":"“Uzmi štap pa ti i tvoj brat Aron skupite zajednicu. Onda, na njihove oči, progovorite pećini da ustupi svoje vode. Iz pećine im izvedi vodu te napoj zajednicu i njezino blago.”"},{"v":9,"t":"Mojsije uzme štap ispred Jahve kako mu je naredio."},{"v":10,"t":"Zatim Mojsije i Aron skupe zbor pred pećinu pa im Mojsije rekne: “Čujte, buntovnici! Hoćemo li vam iz ove pećine izvesti vodu?”"},{"v":11,"t":"Zatim Mojsije podigne ruku i dvaput udari štapom o pećinu: voda provali u obilju, pa su mogli piti i zajednica i njezino blago."},{"v":12,"t":"Potom će Jahve Mojsiju i Aronu: “Budući da se niste pouzdavali u me i niste me svetim očitovali u očima sinova Izraelovih, nećete uvesti ovaj zbor u zemlju koju im dajem.”"},{"v":13,"t":"To su Meripske vode, kraj njih su se Izraelci prepirali s Jahvom, a on se pokazao svetim."},{"v":14,"t":"Iz Kadeša pošalje Mojsije glasnike: “Kralju Edoma. Ovako veli tvoj brat Izrael: 'Ti znaš sve jade koji su nas snašli."},{"v":15,"t":"Naši se preci spustiše u Egipat. U Egiptu smo proboravili mnogo vremena. Egipćani su s nama i s našim precima loše postupali."},{"v":16,"t":"Stoga smo vapili Jahvi, i on ču naš glas i posla anđela koji nas izbavi iz Egipta. Evo nas sad u Kadešu, gradu uz rub tvoga područja."},{"v":17,"t":"Pusti nas da prođemo kroz tvoju zemlju. Nećemo ići preko polja ni vinograda niti ćemo piti vodu iz bunara; ići ćemo Kraljevskim putem, ne skrećući ni desno ni lijevo, dok ne prođemo tvoje područje.”"},{"v":18,"t":"Edom mu odgovori: “Ne prolazi preko moje zemlje, jer eto me s mačem preda te!”"},{"v":19,"t":"“Ići ćemo utrenikom”, rekoše Izraelci, “a budemo li pili tvoje vode, mi i naša stada, za to ćemo ti platiti. Ništa više, samo da prođemo pješice.”"},{"v":20,"t":"“Ne prolazi!” - odgovori. I Edom mu izađe u susret s mnogo ljudi i s velikom silom."},{"v":21,"t":"Tako Edom nije dopustio Izraelu da prođe kroz njegovo područje i Izrael se okrenu od njega."},{"v":22,"t":"Zaputivši se od Kadeša, stigoše Izraelci, sva zajednica, k brdu Horu."},{"v":23,"t":"Kod brda Hora, uz među edomsku, reče Jahve Mojsiju i Aronu:"},{"v":24,"t":"“Neka se Aron pridruži svojim precima! Neće ući u zemlju koju dajem Izraelcima, jer ste se oprli mojoj zapovijedi kod Meripskih voda."},{"v":25,"t":"Uzmi Arona i njegova sina Eleazara, pa ih izvedi na brdo Hor."},{"v":26,"t":"I svuci Aronu njegove haljine pa ih obuci njegovu sinu Eleazaru. Aron će se pridružiti precima, umrijet će ondje.”"},{"v":27,"t":"Mojsije učini kako naredi Jahve. Pred svom zajednicom popeše se na brdo Hor."},{"v":28,"t":"Mojsije svuče s Arona njegove haljine te ih obuče njegovu sinu Eleazaru. Ondje navrh brda umrije Aron. Zatim se Mojsije i Eleazar spustiše s brda."},{"v":29,"t":"Sva zajednica vidje da je Aron preminuo i sav dom Izraelov oplakivaše Arona trideset dana."}]},"21":{"hr":[{"v":1,"t":"Kralj Arada, Kanaanac koji je živio u Negebu, ču da Izrael dolazi Atarimskim putem, pa navali na Izraela i neke njegove zarobi."},{"v":2,"t":"Tada se Izrael ovako zavjetova Jahvi: “Ako u moje ruke izručiš ovaj narod, potpuno ću uništiti njegove gradove.”"},{"v":3,"t":"Jahve usliša glas Izraela i predade mu Kanaance. A Izrael njih i njihove gradove 'heremom' uništi. Stoga se ono mjesto prozva Horma."},{"v":4,"t":"Od brda Hora zapute se prema Crvenom moru da zaobiđu zemlju edomsku. Narod putem postane nestrpljiv."},{"v":5,"t":"I počne govoriti i protiv Boga i protiv Mojsija: “Zašto nas izvedoste iz Egipta da pomremo u ovoj pustinji? Nema kruha, nema vode, a to bijedno jelo već se ogadilo dušama našim.”"},{"v":6,"t":"Onda Jahve pošalje na narod ljute zmije; ujedale ih one, tako te pomrije mnogo naroda u Izraelu."},{"v":7,"t":"Dođe narod k Mojsiju pa reče: “Sagriješili samo kad smo govorili protiv Jahve i protiv tebe. Pomoli se Jahvi da ukloni zmije od nas!” Mojsije se pomoli za narod,"},{"v":8,"t":"i Jahve reče Mojsiju: “Napravi otrovnicu i stavi je na stup: tko god bude ujeden, ostat će na životu ako je pogleda.”"},{"v":9,"t":"Mojsije napravi zmiju od mjedi i postavi je na stup. Kad bi koga ujela ljutica, pogledao bi u mjedenu zmiju i ozdravio."},{"v":10,"t":"Pođu Izraelci i utabore se u Obotu."},{"v":11,"t":"Potom se zapute iz Obota i utabore se kraj Ije-Abarima, u pustinji što je nasuprot Moabu, sa strane sunčeva izlaska."},{"v":12,"t":"Odande otputuju te se utabore u dolini Zaredu."},{"v":13,"t":"Odande krenu i utabore se s onu stranu Arnona, koji je u pustinji a izvire u području Amorejaca. Jer je Arnon granica moapska između Moabaca i Amorejaca."},{"v":14,"t":"Zato se veli u “Knjizi Jahvinih vojni”: “Vaheb kod Sufe i doline arnonske"},{"v":15,"t":"i padine doline što se naginje prema mjestu Aru i naslanja se na granicu moapsku ...”"},{"v":16,"t":"Odande odoše u Beer. To je bunar o kojem je Jahve rekao Mojsiju: “Skupi narod da im dam vode!”"},{"v":17,"t":"Tada Izrael zapjeva ovu pjesmu: “Proključaj, studenče! A vi ga uznosite:"},{"v":18,"t":"knezovi ga iskopali, prvaci narodni izdubli žezlom, štapom svojim.” Iz pustinje odu u Matanu,"},{"v":19,"t":"iz Matane u Nahaliel, a iz Nahaliela u Bamot;"},{"v":20,"t":"iz Bamota u dolinu što se stere u moapskom polju, prema vrhuncu Pisge, s koje se pruža vidik na pustaru."},{"v":21,"t":"Sad Izrael posla glasnike Sihonu, amorejskome kralju, s porukom:"},{"v":22,"t":"“Pusti da prođem preko tvoje zemlje. Nećemo zalaziti u polja i u vinograde, niti ćemo piti vode iz bunara. Ići ćemo Kraljevskim putem dok ne prođemo tvoje područje.”"},{"v":23,"t":"Ali Sihon ne dopusti Izraelu da prođe njegovim područjem, nego skupi sav svoj narod te izađe u pustinju da presretne Izraelce. Stigavši do Jahze, zavojuje na Izraela."},{"v":24,"t":"Ali ga Izrael potuče oštrim mačem i osvoji njegovu zemlju od Arnona do Jaboka, do Amonaca, jer je Az ležao na granici Amonaca."},{"v":25,"t":"Izrael zauzme sve one gradove i Izrael se nastani u svim onim gradovima Amorejaca; u Hešbonu i svim njegovim naseljima."},{"v":26,"t":"Kako je Hešbon bio glavni grad Sihona, amorejskog kralja, koji je ratovao protiv prijašnjega moapskoga kralja te osvojio svu njegovu zemlju do Arnona,"},{"v":27,"t":"kažu zato pjesnici: “Hrabro, o Hešbone, dobro sazdani, čvrsto posađeni grade Sihonov!"},{"v":28,"t":"Iz Hešbona oganj suknu, plamen iz grada Sihonova, sažga Ar moapski, proždrije visove arnonske."},{"v":29,"t":"Teško tebi, Moabe! Propao si, narode Kemošev! Od sinova bjegunce učini, a od kćeri svojih ropkinje Sihonu, kralju amorejskom."},{"v":30,"t":"Pobili smo ih; propao je Hešbon do Dibona: sve smo razorili do Nofaha, što je blizu Medebe ...”"},{"v":31,"t":"Tako se Izrael nastani u zemlji Amorejaca."},{"v":32,"t":"Mojsije se uputi da izvidi Jazer. Potom zauzmu njegova naselja a rastjeraju Amorejce koji bijahu ondje."},{"v":33,"t":"Okrenu se onda i pođu prema Bašanu. A bašanski kralj Og presrete ih sa svim svojim narodom da zapodjene boj kod Edreja."},{"v":34,"t":"Ali Jahve reče Mojsiju: “Ne boj ga se! Predao sam u tvoje ruke njega, sav njegov narod i njegovu zemlju. Postupi s njim kako si postupio s amorejskim kraljem Sihonom koji je boravio u Hešbonu.”"},{"v":35,"t":"I potukoše ga, i sinove njegove, i sav njegov narod, tako da nitko ne uteče. Potom zaposjedoše njegovu zemlju."}]},"22":{"hr":[{"v":1,"t":"Poslije toga Izraelci otputuju i utabore se na Moapskim poljanama, s onu stranu Jordana, nasuprot Jerihonu."},{"v":2,"t":"Balak, sin Siporov, vidje sve što Izrael učini Amorejcima."},{"v":3,"t":"Moab se uvelike poboja toga naroda jer je bio brojan. Moaba obuze strah od Izraelaca."},{"v":4,"t":"Zato reče Moab midjanskim starješinama: “Sad će ova rulja oko nas sve popasti kao što vol popase travu po polju.” Balak, sin Siporov, bijaše moapski kralj u ono vrijeme."},{"v":5,"t":"On pošalje glasnike Bileamu, sinu Beorovu, u Petoru, koji se nalazi na Rijeci, u zemlji Amonaca. Pozove ga rekavši: “Evo je došao neki narod iz Egipta; evo je prekrio lice zemlje i naselio se uza me."},{"v":6,"t":"Zato dođi i prokuni mi ovaj narod jer je jači od mene. Tako ću ga moći svladati i istjerati iz zemlje. A znam da je blagoslovljen onaj koga blagosloviš, a proklet onaj koga prokuneš.”"},{"v":7,"t":"Starješine moapske i starješine midjanske krenu s nagradom za vračanje u svojim rukama. Stignu Bileamu i prenesu mu Balakovu poruku."},{"v":8,"t":"On im rekne: “Prenoćite ovdje te ću vam odgovoriti prema onome što mi Jahve kaže.” Tako moapski knezovi ostanu kod Bileama."},{"v":9,"t":"Bog dođe Bileamu i upita: “Tko su ti ljudi s tobom?” Bileam odgovori Bogu:"},{"v":10,"t":"“Poslao ih k meni Balak, sin Siporov, moapski kralj, s porukom:"},{"v":11,"t":"'Evo je neki narod došao iz Egipta i prekrio lice zemlje. Dođi da ga prokuneš. Tako ću ga moći svladati i protjerati.'”"},{"v":12,"t":"Ali Bog reče Bileamu: “Nemoj ići s njima! Nemoj proklinjati onaj narod jer je blagoslovljen.”"},{"v":13,"t":"Ujutro Bileam ustane te će Balakovim knezovima: “Odlazite u svoju zemlju jer mi ne da Jahve da pođem s vama.”"},{"v":14,"t":"Moapski se knezovi dignu, odu Balaku pa mu reknu: “Bileam nije htio poći s nama.”"},{"v":15,"t":"Balak opet pošalje knezove, brojnije i uglednije od prvih."},{"v":16,"t":"Oni dođu Bileamu i reknu mu: “Ovako je poručio Balak, sin Siporov: 'Ne skanjuj se nego dođi k meni."},{"v":17,"t":"Bogato ću te nagraditi i učinit ću sve što mi kažeš. Dođi, molim te, i prokuni mi ovaj narod!'”"},{"v":18,"t":"Ali Bileam odgovori Balakovim slugama: “Da mi Balak dadne svoju kuću punu srebra i zlata, ne bih mogao prestupiti zapovijedi Jahve, Boga svoga, da učinim išta, bilo veliko bilo malo."},{"v":19,"t":"Ali provedite ovdje i vi noć da doznam što će mi Jahve još kazati.”"},{"v":20,"t":"Noću Bog dođe Bileamu pa mu rekne: “Ako su ti ljudi došli da te pozovu, ustani, pođi s njima! Ali da činiš samo što ti ja reknem!”"},{"v":21,"t":"Ustane Bileam ujutro, osamari svoju magaricu i ode s moapskim knezovima."},{"v":22,"t":"No Božja srdžba usplamtje što je on pošao. Zato anđeo Jahvin stade na put da ga spriječi. On je jahao na svojoj magarici, a pratila ga njegova dva momka."},{"v":23,"t":"Kad magarica opazi anđela Jahvina kako stoji na putu s isukanim mačem u ruci, skrene sa staze i pođe preko polja. Bileam poče tući magaricu da je vrati na put."},{"v":24,"t":"Anđeo Jahvin tada stade na uskom prolazu, među vinogradima, a bijaše ograda i s ove i s one strane."},{"v":25,"t":"Magarica, spazivši Jahvina anđela, stisne se uza zid i o zid pritisne Bileamovu nogu. On je opet poče tući."},{"v":26,"t":"Anđeo Jahvin pođe naprijed te stade na usko mjesto gdje nije bilo prostora da se provuče ni desno ni lijevo."},{"v":27,"t":"Kad je magarica ugledala Jahvina anđela, legne pod Bileamom. Bileam pobjesni i poče tući magaricu štapom."},{"v":28,"t":"Tada Jahve otvori usta magarici te ona progovori Bileamu: “Što sam ti učinila da si me tukao tri puta?”"},{"v":29,"t":"Bileam odgovori magarici: “Što sa mnom zbijaš šalu! Da mi je mač u ruci, sad bih te ubio!”"},{"v":30,"t":"A magarica uzvrati Bileamu: “Zar ja nisam tvoja magarica na kojoj si jahao svega svoga vijeka do danas? Jesam li ti običavala ovako?” - “Nisi!” - odgovori on."},{"v":31,"t":"Tada Jahve otvori oči Bileamu i on opazi anđela Jahvina kako stoji na putu s golim mačem u ruci. Pognu on glavu i pade ničice."},{"v":32,"t":"Onda će mu anđeo Jahvin: “Zašto si tukao svoju magaricu već tri puta? TÓa ja sam istupio da te spriječim, jer te put meni naočigled vodi u propast."},{"v":33,"t":"Magarica me opazila i preda mnom se uklonila sva tri puta. Da mi se nije uklanjala, već bih te ubio, a nju ostavio na životu.”"},{"v":34,"t":"Onda će Bileam anđelu Jahvinu: “Sagriješio sam! Nisam znao da ti preda mnom stojiš na putu. Ali sad, ako je zlo u tvojim očima, ja ću se vratiti.”"},{"v":35,"t":"Ali anđeo Jahvin odvrati Bileamu: “Idi s tim ljudima, ali samo ono govori što ti ja kažem.” Tako Bileam ode s Balakovim knezovima."},{"v":36,"t":"Kad je Balak čuo da Bileam dolazi, iziđe mu u susret do grada Moaba što se nalazi na granici Arnona, na kraju područja."},{"v":37,"t":"“Zar nisam uporno po te slao i pozivao te? Zašto mi nisi došao?” reče Balak Bileamu. “Zar te zaista ne mogu bogato nagraditi?”"},{"v":38,"t":"“Evo sam ti došao”, reče Bileam Balaku. “Ali hoću li ti moći sada što kazati? Samo što mi Bog stavi na jezik, to ću govoriti.”"},{"v":39,"t":"Pođe zatim Bileam s Balakom i dođoše u Kirjat Husot."},{"v":40,"t":"Žrtvova Balak i krupne i sitne stoke te od toga pruži Bileamu i knezovima koji su ga pratili."},{"v":41,"t":"Sutradan uze Balak Bileama i odvede ga gore na Bamot-Baal, odakle mogaše vidjeti krajnji dio naroda."}]},"23":{"hr":[{"v":1,"t":"I Bileam reče Balaku: “Ovdje mi načini sedam žrtvenika; ovdje mi pripravi sedam junaca i sedam ovnova.”"},{"v":2,"t":"Balak učini kako je Bileam rekao. A onda Balak i Bileam prinesu po jednoga junca i ovna na svakome žrtveniku."},{"v":3,"t":"Potom će Bileam Balaku: “Ti stoj kod svoje paljenice, a ja idem ne bih li se sreo s Jahvom, pa što mi očituje, kazat ću ti.” I ode na osamljeno mjesto."},{"v":4,"t":"I Bog srete Bileama, koji mu reče: “Sedam sam žrtvenika podigao i prinio na svakome po jednoga junca i ovna.”"},{"v":5,"t":"A Jahve stavi riječi u usta Bileamu te mu zapovjedi: “Vrati se Balaku i ovako govori.”"},{"v":6,"t":"Bileam se vrati k njemu, a on stajaše uza svoju paljenicu i s njim svi knezovi moapski."},{"v":7,"t":"Tada on poče svoju pjesmu i reče: “Iz Arama dovede me Balak, kralj Moaba, iz strana istočnih: 'Dođi, prokuni mi Jakova, dođi, gromom udri Izraela!'"},{"v":8,"t":"Kako mogu proklinjati koga Bog ne proklinje? Kako gromom udarati koga Jahve ne udara?"},{"v":9,"t":"Jer s vrha hridi ja ga gledam, s visoka ga motrim brijega. Gle naroda koji odvojeno živi, među narode on se ne broji."},{"v":10,"t":"Prah Jakovljev tko će prebrojiti; pijesak Izraela tko će izmjeriti! O, da mi je umrijeti smrću pravednika! O, da svršetak moj bude kao njegov!”"},{"v":11,"t":"“Što mi to uradi!” - reče Balak Bileamu. “Dovedoh te da prokuneš moje neprijatelje, a kad tamo, ti ih blagoslovom obasu!”"},{"v":12,"t":"On odgovori: “Zar mi nije dužnost kazati što mi Jahve stavlja u usta?”"},{"v":13,"t":"“Hajde sa mnom na drugo mjesto, odakle ga možeš svega vidjeti” zamoli ga Balak. “Odavde mu vidiš samo jedan kraj, a ne vidiš ga svega. Odande mi ga prokuni!”"},{"v":14,"t":"Povede ga zatim na Sede Sofim, na vrh Pisge. Tu sagradi sedam žrtvenika i na svakom žrtveniku prinese po jednoga junca i ovna."},{"v":15,"t":"Bileam tada rekne Balaku: “Stoj ovdje kraj svoje paljenice, a ja odoh onamo na susret Bogu.”"},{"v":16,"t":"Jahve sretne Bileama; stavi riječi u njegova usta te mu zapovjedi: “Vrati se k Balaku i tako govori!”"},{"v":17,"t":"I vrati se on Balaku, koji stajaše uza svoju paljenicu i s njim moapski knezovi. Balak ga zapita: “Što je Jahve rekao?”"},{"v":18,"t":"Tada Bileam započe svoju pjesmu i reče: “Ustani, Balače, i poslušaj! Uhom me posluhni, sine Siporov!"},{"v":19,"t":"Bog nije čovjek da bi slagao, nije sin Adama da bi se kajao. Zar on kada rekne, a ne učini, zar obeća, pa ne ispuni?"},{"v":20,"t":"Gle, primih od Boga da blagoslovim, blagoslovit ću i povuć' neću blagoslova."},{"v":21,"t":"U Jakovu nesreće ne nazreh, nit' nevolje vidjeh u Izraelu. Jahve, Bog njegov, s njime je, poklik kralju u njemu odzvanja."},{"v":22,"t":"Iz Egipta Bog ga je izveo, on je njemu k'o rozi bivola."},{"v":23,"t":"Gatanja nema protiv Jakova nit' protiv Izraela vračanja. I kada budu rekli Jakovu i Izraelu: 'Što radi Bog?'"},{"v":24,"t":"gle, ustat će narod k'o lavica, dići će se poput lava: leći neće dok plijen ne proguta, dok ne popije krv pobijenih.”"},{"v":25,"t":"Zatim Balak reče Bileamu: “Nemoj ga ni kletvom kleti, ali ni blagoslovom blagoslivljati.”"},{"v":26,"t":"Bileam odvrati Balaku. “Zar ti nisam rekao: sve što Jahve kaže, to ću činiti.”"},{"v":27,"t":"Potom Balak reče Bileamu: “Hajde! Odvest ću te na drugo mjesto. Možda će Bogu biti pravo da mi ga odande prokuneš.”"},{"v":28,"t":"I odvede Balak Bileama na vrh Peora, odakle se pruža vidik na pustaru."},{"v":29,"t":"“Sagradi mi ovdje sedam žrtvenika”, reče Bileam Balaku. “Nadalje, pripremi mi ovdje sedam junaca i sedam ovnova.”"},{"v":30,"t":"Balak učini kako je Bileam rekao i prinese po jednoga junca i ovna na svakome žrtveniku."}]},"24":{"hr":[{"v":1,"t":"Kad opazi Bileam da je Jahvi drago što on blagoslivlja Izraela, ne htjede više ni ići kao prije u potragu za znamenjima, nego se licem okrenu prema pustari."},{"v":2,"t":"Bileam podiže oči i vidje Izraela utaborena po njegovim plemenima. Na nj siđe Duh Božji"},{"v":3,"t":"i on poče svoju pjesmu te reče: “Proročanstvo Bileama, sina Beorova, proročanstvo čovjeka pronicava pogleda,"},{"v":4,"t":"proročanstvo onoga koji riječi Božje sluša, koji vidi viđenja Svesilnoga, koji pada i oči mu se otvaraju."},{"v":5,"t":"Kako su lijepi ti šatori, Jakove, i stanovi tvoji, Izraele!"},{"v":6,"t":"Kao dolovi što se steru, kao vrtovi uz obalu rijeke, kao aloje što ih Jahve posadi, kao cedri pokraj voda!"},{"v":7,"t":"Iz potomstva junak mu izlazi, nad mnogim on vlada narodima. Kralj će njegov nadvisit' Agaga, uzdiže se kraljevstvo njegovo."},{"v":8,"t":"Iz Egipta Bog ga izveo, on je njemu k'o rozi bivola. On proždire narode dušmanske, on njihove kosti drobi."},{"v":9,"t":"Skupio se, polegao poput lava, poput lavice: tko ga podići smije? Blagoslovljen bio tko te blagoslivlje, proklet da je tko tebe proklinje!”"},{"v":10,"t":"I usplamtje srdžbom Balak na Bileama i udari rukom o ruku. “Pozvao sam te da prokuneš moje neprijatelje”, reče Balak Bileamu, “a kad tamo, ti ih blagoslovi evo triput!"},{"v":11,"t":"Nosi se odmah u svoj kraj. Bio sam rekao: dostojno ću te počastiti! A eto, Jahve te liši časti.”"},{"v":12,"t":"Nato Bileam odgovori Balaku: “Zar nisam rekao i tvojim glasnicima koje si k meni poslao:"},{"v":13,"t":"'Da mi Balak dadne svoju kuću punu srebra i zlata, ne bih mogao prestupiti zapovijed Jahvinu i po svojoj volji činiti bilo dobro, bilo zlo; ono što kaže Jahve, to ću i ja reći.'"},{"v":14,"t":"A sada, kad, evo, odlazim k svome narodu, hajde da ti objavim što će ovaj narod učiniti tvome narodu u budućnosti!”"},{"v":15,"t":"I poče svoju pjesmu i reče: “Proročanstvo Bileama, sina Beorova, proročanstvo čovjeka pronicava pogleda,"},{"v":16,"t":"proročanstvo onoga koji riječi Božje sluša, koji poznaje mudrost Svevišnjega, koji vidi viđenja Svesilnoga, koji pada i oči mu se otvaraju."},{"v":17,"t":"Vidim ga, ali ne sada: motrim ga, al' ne iz blizine: od Jakova zvijezda izlazi, od Izraela žezlo se diže. On Moabu razbija bokove i svu djecu Šetovu zatire!"},{"v":18,"t":"Edom će njegovim postati posjedom, a Seir zemljom osvojenom. Razvija snagu svoju Izrael,"},{"v":19,"t":"Jakov vlada nad neprijateljima i uništava preživjele iz Ira.”"},{"v":20,"t":"Bileam se zagleda u Amaleka te poče svoju pjesmu i reče: “Amalek je prvenac među narodima, ali vječna propast njegov je svršetak.”"},{"v":21,"t":"Onda se zagleda u Kenijce te poče svoju pjesmu i reče: “Tvrd je stan tvoj, Kajine, na timoru ti gnijezdo savijeno!"},{"v":22,"t":"Al' gnijezdo pripada Beoru; dokle ćeš Ašuru robovati?”"},{"v":23,"t":"Opet poče svoju pjesmu i reče: “Narodi pomorski sabiru se sa sjevera,"},{"v":24,"t":"a brodovlje od strane Kitima. Podjarmljuju Ašur, podjarmljuju Heber, pa i njega će propast stići vječita.”"},{"v":25,"t":"Potom ustade Bileam te se uputi natrag u svoj kraj. A i Balak ode svojim putem."}]},"25":{"hr":[{"v":1,"t":"Dok je Izrael boravio u Šitimu, narod se upusti u blud s Moapkama."},{"v":2,"t":"One pozivahu narod na žrtvovanje svojim bogovima, a narod sudjelovaše u njihovim gozbama i klanjaše se njihovim bogovima."},{"v":3,"t":"Tako se Izrael osramoti s Baalom peorskim. I Jahve planu gnjevom na Izraela."},{"v":4,"t":"“Pokupi sve narodne glavare”, reče Jahve Mojsiju. “Objesi ih Jahvi usred bijela dana da se Jahvin gnjev odvrati od Izraela.”"},{"v":5,"t":"Onda Mojsije rekne izraelskim sucima: “Neka svatko pobije one svoje ljude koji su se osramotili s Baalom peorskim.”"},{"v":6,"t":"Baš tada neki Izraelac dođe i dovede k svojoj braći jednu Midjanku naočigled Mojsija i naočigled sve izraelske zajednice koja zaplaka na ulazu u Šator sastanka."},{"v":7,"t":"Kad to opazi Pinhas, sin Eleazara, sina svećenika Arona, ustade ispred zajednice: uze koplje u ruku"},{"v":8,"t":"i pođe za Izraelcem u odaje i probode ih oboje, Izraelca i ženu; nju kroza slabine. Tako pomor Izraelaca prestade."},{"v":9,"t":"A onih koji su od pomora pomrli bilo je dvadeset i četiri tisuće."},{"v":10,"t":"Jahve reče Mojsiju:"},{"v":11,"t":"“Pinhas, sin Eleazara, sina svećenika Arona, odvratio je moj gnjev od Izraelaca, obuzet među njima mojim revnovanjem. Zato u svome revnovanju nisam istrijebio izraelskoga naroda."},{"v":12,"t":"Kaži mu dakle: 'S njime, evo, sklapam savez mira."},{"v":13,"t":"Neka to bude za nj i njegove potomke poslije njega savez vječnoga svećeništva, jer je revnovao za svoga Boga i izvršio pomirenje za izraelski narod.'”"},{"v":14,"t":"Ime Izraelcu koji je bio ubijen - onome što je ubijen s Midjankom - bijaše Zimri. Bio je sin Salua, glavara jedne od Šimunovih porodica."},{"v":15,"t":"A ime ubijene žene Midjanke bijaše Kozbi. Bila je kći Surova. Sur je bio glavar jednog plemena, jedne porodice u Midjanu."},{"v":16,"t":"Jahve reče Mojsiju:"},{"v":17,"t":"“Navali na Midjance i potuci ih,"},{"v":18,"t":"jer su i oni navaljivali na vas svojim lukavštinama kad su lukavo radili protiv vas u slučaju Peora i svoje sestre Kozbi, kćeri glavara midjanskoga, koja je zaglavila u vrijeme pomora nastalog zbog Peora.”"}]},"26":{"hr":[{"v":1,"t":"Poslije toga zla Jahve reče Mojsiju i Eleazaru, sinu svećenika Arona:"},{"v":2,"t":"“Obavite popis sve zajednice sinova Izraelovih, po njihovim porodicama, popišite sve, od dvadeset godina pa naviše, koji su u Izraelu sposobni za borbu.”"},{"v":3,"t":"Mojsije, dakle, i svećenik Eleazar popišu ih na Moapskim poljanama, uz Jordan blizu Jerihona,"},{"v":4,"t":"sve od dvadeset godina pa naviše, kako je Jahve naredio Mojsiju i Izraelcima. Sinovi Izraelovi koji su izašli iz zemlje egipatske bili su:"},{"v":5,"t":"Izraelov prvorođenac Ruben. Sinovi Rubenovi: od Henoka rod Henokovaca; od Palua rod Paluovaca;"},{"v":6,"t":"od Hesrona rod Hesronovaca i od Karmija rod Karmijevaca."},{"v":7,"t":"To su rodovi Rubenovaca. Njih je bilo četrdeset i tri tisuće sedam stotina i trideset."},{"v":8,"t":"Paluov sin bijaše Eliab,"},{"v":9,"t":"a sinovi Eliabovi: Nemuel, Datan i Abiram. Taj Datan i Abiram bijahu ugledni članovi zajednice koji se podigoše protiv Mojsija i Arona u buni Korahovoj, kad se pobuniše protiv Jahve."},{"v":10,"t":"Nato je zemlja rastvorila svoje ralje i progutala ih zajedno s Korahom, kad je smrt pograbila tu skupinu i oganj proždro dvjesta i pedeset ljudi. Tako su postali opomenom."},{"v":11,"t":"No sinovi Korahovi ne izginuše."},{"v":12,"t":"Sinovi Šimunovi po svojim rodovima: od Nemuela rod Nemuelovaca; od Jamina rod Jaminovaca; od Jakina rod Jakinovaca;"},{"v":13,"t":"od Zeraha rod Zerahovaca i od Šaula rod Šaulovaca."},{"v":14,"t":"To su rodovi Šimunovaca, njih dvadeset i dvije tisuće i dvjesta."},{"v":15,"t":"Sinovi Gadovi po svojim rodovima: od Sefona rod Sefonovaca; od Hagija rod Hagijevaca; od Šunija rod Šunijevaca;"},{"v":16,"t":"od Oznija rod Oznijevaca; od Erija rod Erijevaca;"},{"v":17,"t":"od Aroda roda Arodovaca i od Arelija rod Arelijevaca."},{"v":18,"t":"To su rodovi Gadovih potomaka. Njih je upisano četrdeset tisuća i pet stotina."},{"v":19,"t":"Judini sinovi: Er i Onan. I Er i Onan umriješe u zemlji kanaanskoj."},{"v":20,"t":"Sinovi Judini po svojim rodovima bijahu: od Šele rod Šelinaca; od Peresa rod Peresovaca i od Zeraha rod Zerahovaca."},{"v":21,"t":"Peresovi su sinovi opet bili: od Hesrona rod Hesronovaca i od Hamula rod Hamulovaca."},{"v":22,"t":"To su Judini rodovi. Njih je upisano sedamdeset i šest tisuća i petsto."},{"v":23,"t":"Sinovi Jisakarovi, prema svojim rodovima: od Tole rod Tolinaca; od Puve rod Puvinaca;"},{"v":24,"t":"od Jašuba rod Jašubovaca i od Šimrona rod Šimronovaca."},{"v":25,"t":"To su Jisakarovi rodovi. Njih je upisano šezdeset i četiri tisuće i trista."},{"v":26,"t":"Sinovi Zebulunovi, po svojim rodovima: od Sereda rod Seredovaca; od Elona rod Elonovaca i od Jahleela rod Jahleelovaca."},{"v":27,"t":"To su rodovi Zebulunovaca. Njih je upisano šezdeset tisuća i pet stotina."},{"v":28,"t":"Sinovi Josipovi, po svojim rodovima: Manaše i Efrajim."},{"v":29,"t":"Sinovi Manašeovi: od Makira rod Makirovaca. Makiru se rodio Gilead. Od Gileada rod Gileadovaca."},{"v":30,"t":"Ovo su bili sinovi Gileadovi: od Jezera rod Jezerovaca; od Heleka rod Helekovaca;"},{"v":31,"t":"od Asriela rod Asrielovaca; od Šekema rod Šekemovaca;"},{"v":32,"t":"od Šemide rod Šemidinaca i od Hefera rod Heferovaca."},{"v":33,"t":"Heferov sin Selofhad nije imao sinova, nego kćeri. Imena Selofhadovih kćeri bila su: Mahla, Noa, Hogla, Milka i Tirsa."},{"v":34,"t":"To su Manašeovi rodovi. Njih je upisano pedeset i dvije tisuće i sedam stotina."},{"v":35,"t":"Ovo su opet sinovi Efrajimovi, po svojim rodovima: od Šutelaha rod Šutelahovaca; od Bekera rod Bekerovaca i od Tahana rod Tahanovaca."},{"v":36,"t":"Ovo su sinovi Šutelahovi: od Erana rod Eranovaca."},{"v":37,"t":"To su rodovi Efrajimovih sinova. Njih je upisano trideset i dvije tisuće i pet stotina. To su sinovi Josipovi, po svojim rodovima."},{"v":38,"t":"Sinovi Benjaminovi, po svojim rodovima: od Bele rod Belinaca; od Ašbela rod Ašbelovaca; od Ahirama rod Ahiramovaca;"},{"v":39,"t":"od Šefufama rod Šefufamovaca i od Hufama rod Hufamovaca."},{"v":40,"t":"Belini sinovi bili su: Ard i Naaman. I tako, od Arda rod Ardovaca, a od Naamana rod Naamanovaca."},{"v":41,"t":"To su sinovi Benjaminovi, po svojim rodovima. Njih je upisano četrdeset i pet tisuća i šest stotina."},{"v":42,"t":"Ovo su sinovi Danovi, po svojim rodovima: od Šuhama rod Šuhamovaca. To su sinovi Danovi, prema svojim rodovima."},{"v":43,"t":"Od svih rodova Šuhamovaca bilo je upisano šezdeset i četiri tisuće i četiri stotine."},{"v":44,"t":"Sinovi Ašerovi, po svojim rodovima: od Jimne rod Jimninaca; od Jišvija rod Jišvijevaca i od Berije rod Berijevaca."},{"v":45,"t":"Od sinova Berijinih: od Hebera rod Heberovaca i od Malkiela rod Malkielovaca."},{"v":46,"t":"Ašerovoj kćeri bilo je ime Serah."},{"v":47,"t":"To su rodovi Ašerovih sinova. Njih je upisano pedeset i tri tisuće i četiri stotine."},{"v":48,"t":"Sinovi Naftalijevi, po svojim rodovima: od Jahseela rod Jahseelovaca; od Gunija rod Gunijevaca;"},{"v":49,"t":"od Jesera rod Jeserovaca i od Šilema rod Šilemovaca."},{"v":50,"t":"To su rodovi Naftalijevaca. Po njihovim rodovima upisano ih je četrdeset i pet tisuća i četiri stotine."},{"v":51,"t":"Bilo je, dakle, upisanih Izraelaca šest stotina i jedna tisuća i sedam stotina i trideset."},{"v":52,"t":"Jahve reče Mojsiju:"},{"v":53,"t":"“Tima neka se razdijeli zemlja u baštinu prema broju osoba."},{"v":54,"t":"Većem broju povećaj njegovu baštinu, a manjem smanji njegovu baštinu; neka se svakomu dadne njegova baština prema broju upisanih."},{"v":55,"t":"Ali zemlja neka se podijeli kockom: neka se primi u baštinu prema djedovskim plemenskim imenima."},{"v":56,"t":"Baština se ima podijeliti kockom svakom plemenu prema njegovoj veličini.”"},{"v":57,"t":"Ovo je popis Levijevaca, po njihovim rodovima: od Geršona rod Geršonovaca; od Kehata rod Kehatovaca i od Merarija rod Merarijevaca."},{"v":58,"t":"Ovo su rodovi Levijevaca: rod Libnijevaca, rod Hebronovaca, rod Mahlijevaca, rod Mušijevaca i rod Korahovaca. Kehatu se rodio Amram."},{"v":59,"t":"Amramovoj ženi bijaše ime Jokebeda. Bila je kći Levijeva, koja se Leviju rodila u Egiptu. Ona je Amramu rodila: Arona, Mojsija i njihovu sestru Mirjam."},{"v":60,"t":"Aronu se rodili: Nadab, Abihu, Eleazar i Itamar."},{"v":61,"t":"Nadab i Abihu poginuli su kad su prinosili neposvećenu vatru pred Jahvom."},{"v":62,"t":"Svih je popisanih muškaraca od jednog mjeseca pa naviše bilo dvadeset i tri tisuće. Oni nisu bili popisani s Izraelcima i nije im bila dodijeljena baština među Izraelcima."},{"v":63,"t":"To su, dakle, oni koje je popisao Mojsije i svećenik Eleazar; oni su obavili ovaj popis Izraelaca uz Jordan, na Moapskim poljanama nasuprot Jerihonu."},{"v":64,"t":"Među njima nije bilo ni jednoga od onih koje su popisali Mojsije i svećenik Aron kad su popisivali Izraelce u Sinajskoj pustinji."},{"v":65,"t":"Jer Jahve bijaše za njih rekao: “Neka pomru u pustinji i neka nitko od njih ne ostane, osim Kaleba, sina Jefuneova, i Jošue, sina Nunova!”"}]},"27":{"hr":[{"v":1,"t":"Tada pristupiše kćeri Selofhada, sina Heferova, sina Gileadova, sina Makirova, sina Manašeova iz roda Josipova sina Manašea. A imena kćeri bila su: Mahla, Noa, Hogla, Milka i Tirsa."},{"v":2,"t":"One stanu pred Mojsija, pred svećenika Eleazara, pred glavare i svu zajednicu na ulazu u Šator sastanka pa reknu:"},{"v":3,"t":"“Naš je otac umro u pustinji. Nije pripadao družini što se pobunila protiv Jahve - Korahovoj družini - nego je umro od svoga vlastitoga grijeha. Sinova nije imao."},{"v":4,"t":"Zašto bi se odstranilo ime našega oca iz njegova roda? Budući da nije imao sina, daj nama posjed među braćom našega oca!”"},{"v":5,"t":"Mojsije iznese njihov slučaj pred Jahvu."},{"v":6,"t":"A Jahve reče Mojsiju:"},{"v":7,"t":"“Selofhadove kćeri pravo kažu. Treba svakako da im dadneš posjed koji će biti njihova baština među braćom njihova oca. Prenesi na njih baštinu njihova oca."},{"v":8,"t":"Nadalje, reci Izraelcima: 'Kad koji čovjek umre a ne imadne sina, prenesite njegovu baštinu na njegovu kćer."},{"v":9,"t":"Ne imadne li ni kćeri, predajte baštinu njegovoj braći."},{"v":10,"t":"Ako ne imadne ni braće, njegovu baštinu podajte braći njegova oca."},{"v":11,"t":"Ako mu otac ne imadne braće, baštinu njegovu podajte najbližem rođaku njegova roda: neka je on uzme u posjed.' Neka to bude zakonska odredba Izraelcima, kako je Jahve naredio Mojsiju.”"},{"v":12,"t":"Jahve reče Mojsiju: “Popni se na ovo brdo Abarim i razgledaj zemlju koju dajem Izraelcima."},{"v":13,"t":"A kad budeš razgledao, pridružit ćeš se svojim precima i ti, kako se pridružio i tvoj brat Aron."},{"v":14,"t":"Jer ste se u pobuni zajednice u pustinji Sin usprotivili mojim ustima umjesto da vodom očitujete moju svetost pred njihovim očima.” (To su Meripske vode kod Kadeša u Sinskoj pustinji.)"},{"v":15,"t":"A Jahvi Mojsije progovori ovako:"},{"v":16,"t":"“Neka Jahve, Bog duhova u svakom tijelu, postavi čovjeka nad ovom zajednicom"},{"v":17,"t":"koji će pred njom izlaziti; koji će pred njom stupati; koji će je izvoditi i uvoditi tako da Jahvina zajednica ne bude kao stado što nema pastira.”"},{"v":18,"t":"“Uzmi Jošuu, sina Nunova!” - reče Jahve Mojsiju. “To je čovjek u kome ima duha. Na nj položi ruku svoju!"},{"v":19,"t":"Onda ga odvedi pred svećenika Eleazara i pred svu zajednicu te mu na njihove oči daj naredbe!"},{"v":20,"t":"Predaj mu dio svoje vlasti da ga sluša sva zajednica sinova Izraelovih."},{"v":21,"t":"Neka pristupa k svećeniku Eleazaru, koji će za nj tražiti odluke Urima pred Jahvom. Na njegovu zapovijed neka izlaze i na njegovu zapovijed neka ulaze, oni i svi Izraelci s njim - sva zajednica.”"},{"v":22,"t":"Mojsije učini kako mu je Jahve naredio: uzme Jošuu te ga postavi pred svećenika Eleazara i pred svu zajednicu."},{"v":23,"t":"Položi zatim na nj svoje ruke i dade mu svoje naredbe, kako je Jahve zapovjedio preko Mojsija."}]},"28":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Naredi Izraelcima i reci im: 'Točno u određeno vrijeme prinosite mi moje prinose, moju hranu - žrtve paljene meni na ugodan miris.'"},{"v":3,"t":"Reci im: Ovo su žrtve paljene koje ćete prinositi Jahvi: Svaki dan dva jednogodišnja janjca bez mane kao trajnu paljenicu."},{"v":4,"t":"Jedno janje prinosite jutrom, a drugo janje prinosite u suton."},{"v":5,"t":"A za prinosnicu desetinu efe najboljeg brašna, zamiješena u četvrtini hina čistoga ulja."},{"v":6,"t":"Trajna je to paljenica koja je već bila prinesena na Sinajskom brdu - žrtva spaljena na ugodan miris Jahvi."},{"v":7,"t":"Njezina ljevanica neka se sastoji od četvrtine hina za svako janje. Ljevanica vina neka se Jahvi izlijeva u Svetištu."},{"v":8,"t":"Drugo janje prinosite u suton. Prinosi ga kao i jutarnju prinosnicu i njezinu ljevanicu: kao žrtvu spaljenu Jahvi na ugodan miris.”"},{"v":9,"t":"“Na subotnji dan: dva jednogodišnja janjeta bez mane i dvije desetine efe najboljeg brašna, zamiješena s uljem, za prinosnicu, s njezinom ljevanicom."},{"v":10,"t":"Neka se subotnja paljenica svake subote dodaje trajnoj paljenici i njezinoj ljevanici.”"},{"v":11,"t":"“Na početku vaših mjeseci prinosite Jahvi za paljenicu: dva junca, jednoga ovna i sedam jednogodišnjih janjaca bez mane."},{"v":12,"t":"Za pojedinog junca kao prinosnicu: tri desetine najboljeg brašna zamiješena s uljem; za svakog ovna kao prinosnicu: dvije desetine efe najboljeg brašna zamiješena s uljem."},{"v":13,"t":"Za svako janje jednu desetinu efe najboljeg brašna zamiješena s uljem kao prinosnicu. To je paljenica spaljena na ugodan miris Jahvi."},{"v":14,"t":"Njihove ljevanice neka budu: na junca polovica hina vina; na ovna trećina hina; na janje četvrtina hina. To neka bude mjesečna paljenica na mlađak svakog mjeseca u godini."},{"v":15,"t":"Povrh trajne paljenice neka se Jahvi prinosi jedan jarac kao okajnica s njezinom ljevanicom.”"},{"v":16,"t":"“Prvoga mjeseca, četrnaestoga dana u mjesecu, Jahvina je Pasha,"},{"v":17,"t":"a petnaestoga dana toga mjeseca jest blagdan. Neka se sedam dana jedu beskvasni hljebovi."},{"v":18,"t":"Prvog dana neka bude sveti saziv. Nikakva težačkog posla nemojte raditi."},{"v":19,"t":"Prinesite Jahvi žrtvu paljenu, žrtvu paljenicu: dva junca, jednoga ovna i sedam jednogodišnjih janjaca. Neka vam budu bez mane."},{"v":20,"t":"Njihova prinosnica, od najboljeg brašna zamiješena s uljem, neka bude: tri desetine efe na junca, dvije desetine efe na ovna,"},{"v":21,"t":"a na svakoga od onih sedam janjaca neka bude jedna desetina efe."},{"v":22,"t":"Neka bude jedan jarac kao okajnica, da se nad vama izvrši obred pomirenja."},{"v":23,"t":"Ovo prinosite povrh jutarnje paljenice, koje se prinosi kao trajna paljenica."},{"v":24,"t":"Tako činite svaki dan za sedam dana; to je hrana, žrtva paljena na ugodan miris Jahvi. To neka se prinosi povrh trajne paljenice i njezine ljevanice."},{"v":25,"t":"Sedmoga dana neka vam bude sveti savez. Nikakva težačkog posla nemojte raditi!”"},{"v":26,"t":"“I na Dan prvina - na svoj Blagdan sedmica - kad budete Jahvi prinosili prinosnicu, imajte sveti saziv: nikakva težačkog posla nemojte raditi."},{"v":27,"t":"Za paljenicu na ugodan miris Jahvi prinesite dva junca, jednoga ovna i sedam jednogodišnjih janjaca."},{"v":28,"t":"Njihova prinosnica, od najboljeg brašna zamiješena s uljem, neka bude: na pojedinog junca tri desetine efe, na pojedinoga ovna dvije desetine efe,"},{"v":29,"t":"a jedna desetina efe na svakoga od onih sedam janjaca."},{"v":30,"t":"Neka bude i jedan jarac kao okajnica, da se nad vama izvrši obred pomirenja."},{"v":31,"t":"Prinosite ih povrh trajne paljenice i njezine prinosnice, a neka vam budu bez mane one i njihove ljevanice.”"}]},"29":{"hr":[{"v":1,"t":"“U sedmome mjesecu, na prvi dan mjeseca, imajte sveti saziv. Nikakva težačkog posla nemojte raditi. Neka vam to bude Dan sazivanja."},{"v":2,"t":"Za paljenicu na ugodan miris Jahvi prinesite: jednoga junca, jednoga ovna i sedam jednogodišnjih janjaca bez mane."},{"v":3,"t":"Njihova prinosnica, od najboljeg brašna zamiješena s uljem, neka bude: tri desetine efe na junca, dvije desetine efe na ovna"},{"v":4,"t":"i jedna desetina efe na svakoga od onih sedam janjaca."},{"v":5,"t":"Neka bude jedan jarac kao okajnica, da se nad vama izvrši obred pomirenja."},{"v":6,"t":"Neka to bude povrh paljenice o mlađaku mjesecu i njezine prinosnice, povrh trajne paljenice i njezine prinosnice i povrh njihovih propisanih ljevanica, žrtva spaljena na ugodan miris Jahvi.”"},{"v":7,"t":"“A desetoga dana toga sedmog mjeseca imajte sveti saziv. Postite i nemojte raditi nikakva posla."},{"v":8,"t":"Prinesite paljenicu Jahvi na ugodan miris: jednoga junca, jednoga ovna i sedam jednogodišnjih janjaca. Neka su vam bez mane."},{"v":9,"t":"Njihova prinosnica, od najboljeg brašna zamiješena s uljem, neka bude: tri desetine efe na junca, dvije desetine na jednoga ovna"},{"v":10,"t":"i jedna desetina efe na svakoga od onih sedam janjaca."},{"v":11,"t":"Jedan jarac neka se prinese kao okajnica. To je povrh okajnice na Dan pomirenja, povrh trajne paljenice i njezine prinosnice i njihovih ljevanica.”"},{"v":12,"t":"“Na petnaesti dan sedmoga mjeseca imajte sveti saziv. Nikakva težačkog posla nemojte raditi. Sedam dana svetkujte svečanost Jahvi."},{"v":13,"t":"A za paljenicu, spaljenu na ugodan miris Jahvi, prinesite: trinaest junaca, dva ovna i četrnaest jednogodišnjih janjaca. Neka su bez mane."},{"v":14,"t":"Njihova prinosnica, od najboljeg brašna zamiješena s uljem, neka bude: tri desetine efe na svakoga od trinaest junaca, dvije desetine efe na svakoga od dvaju ovnova"},{"v":15,"t":"i jedna desetina efe na svako pojedino od četrnaestero janjadi. Neka se nadoda jedan jarac kao okajnica."},{"v":16,"t":"To neka bude povrh trajne paljenice, njezine prinosnice i njezine ljevanice."},{"v":17,"t":"Drugog dana: dvanaest junaca, dva ovna, četrnaest jednogodišnjih janjaca bez mane."},{"v":18,"t":"Njihovu prinosnicu i njihove ljevanice prinesite propisno prema broju junaca, ovnova i janjaca."},{"v":19,"t":"Prinesite jednoga jarca kao okajnicu povrh trajne paljenice, njezine prinosnice i njezinih ljevanica."},{"v":20,"t":"Trećeg dana: jedanaest junaca, dva ovna, četrnaest jednogodišnjih janjaca bez mane."},{"v":21,"t":"Njihovu prinosnicu i njihove ljevanice prinesite propisno prema broju junaca, ovnova i janjaca."},{"v":22,"t":"Prinesite jednoga jarca kao okajnicu povrh trajne paljenice, njezine prinosnice i njezine ljevanice."},{"v":23,"t":"Četvrtog dana: deset junaca, dva ovna, četrnaest jednogodišnjih janjaca bez mane."},{"v":24,"t":"Njihovu prinosnicu i njihove ljevanice prinesite propisno prema broju junaca, ovnova i janjaca."},{"v":25,"t":"Jednog jarca prinesite kao okajnicu povrh trajne paljenice, njezine prinosnice i njezine ljevanice."},{"v":26,"t":"Petog dana: devet junaca, dva ovna, četrnaest jednogodišnjih janjaca bez mane."},{"v":27,"t":"Njihovu prinosnicu i njihove ljevanice prinesite propisno prema broju junaca, ovnova i janjaca."},{"v":28,"t":"Prinesite jednog jarca kao okajnicu povrh trajne paljenice, njezine prinosnice i njezine ljevanice."},{"v":29,"t":"Šestog dana: osam junaca, dva ovna, četrnaest jednogodišnjih janjaca bez mane."},{"v":30,"t":"Njihovu prinosnicu i njihove ljevanice prinesite propisno prema broju junaca, ovnova i janjaca."},{"v":31,"t":"Jednoga jarca prinesite kao okajnicu povrh trajne paljenice, njezine prinosnice i njezinih ljevanica."},{"v":32,"t":"Sedmog dana: sedam junaca, dva ovna, četrnaest jednogodišnjih janjaca bez mane."},{"v":33,"t":"Njihovu prinosnicu i njihove ljevanice prinesite propisno prema broju junaca, ovnova i janjaca."},{"v":34,"t":"Jednog jarca prinesite kao okajnicu povrh trajne paljenice, njezine prinosnice i njezine ljevanice."},{"v":35,"t":"Osmog dana imajte svečani zbor. Nikakva težačkog posla nemojte raditi."},{"v":36,"t":"A za paljenicu, spaljenu na ugodan miris Jahvi, prinesite: jednog junca, jednoga ovna i sedam jednogodišnjih janjaca bez mane."},{"v":37,"t":"Njihovu prinosnicu i njihove ljevanice prinesite propisno prema broju junaca, ovnova i janjaca."},{"v":38,"t":"Jednog jarca prinesite kao okajnicu povrh trajne paljenice, njezine prinosnice i njezine ljevanice."},{"v":39,"t":"Na svoje određene blagdane prinesite to Jahvi osim svojih zavjetnica i svojih dragovoljnih žrtava, svojih paljenica, prinosnica, ljevanica i svojih pričesnica.”"}]},"30":{"hr":[{"v":1,"t":"Sve kako mu je Jahve naredio Mojsije kaza Izraelcima."},{"v":2,"t":"Zatim reče Mojsije glavarima plemena Izraelovih: “Ovo je Jahve naredio."},{"v":3,"t":"Ako koji čovjek učini zavjet ili se uz zakletvu obveže da će se nečega odreći, neka ne krši svoje riječi; neka izvrši sve što iz njegovih usta izađe!"},{"v":4,"t":"Ako koja žena učini Jahvi zavjet ili se obveže da će se nečega odreći dok je još mlada, u očevu domu,"},{"v":5,"t":"a otac joj sazna za zavjet i obećanje kojim se obvezala pa joj ništa ne rekne, tada su valjani svi njezini zavjeti i valjano je svako obećanje kojim se obvezala."},{"v":6,"t":"Ali ako joj se otac usprotivi kad sazna, nikakav njezin zavjet ni njezino obećanje kojim se vezala ne vrijedi. Jahve će joj oprostiti jer joj se otac usprotivio."},{"v":7,"t":"Ako se uda dok je pod svojim zavjetima ili pod obećanjem koje je nepromišljeno izišlo iz njezinih usta,"},{"v":8,"t":"pa njezin muž sazna i pošto je saznao ništa joj ne rekne, tada vrijede njezini zavjeti i vrijede obećanja kojima se obvezala."},{"v":9,"t":"No ako se njezin muž usprotivi kad o tom sazna, ukida se time njezin zavjet i obećanje što je nepromišljeno izišlo iz njezinih usta. I Jahve će joj oprostiti."},{"v":10,"t":"A zavjet udovice ili žene otpuštene i sve obveze koje je na se preuzela vrijede za nju."},{"v":11,"t":"Ako se zavjetuje ili se obveže zakletvom na obećanje dok je u kući svoga muža,"},{"v":12,"t":"pa njezin muž sazna i ništa joj ne rekne, ne usprotivi joj se, svaki je njezin zavjet valjan i valjano je svako obećanje kojim se obvezala."},{"v":13,"t":"Ali ako ih njezin muž proglasi ništetnim kad o njima sazna, tada ništa što je izišlo iz njezinih usta, njezini zavjeti ili preuzete obveze neće vrijediti. Muž ih je njezin poništio, i Jahve će joj oprostiti."},{"v":14,"t":"Svaki zavjet i svaku zakletvu koja obvezuje ženu na neko mrtvenje njezin muž može uzdržati na snazi ili poništiti."},{"v":15,"t":"Ako joj muž od dana do dana ništa ne rekne, time potvrđuje sve njezine zavjete i sva njezina obećanja kojima se obvezala; on ih je učinio valjanima ako ništa nije rekao kad je o njima čuo."},{"v":16,"t":"Ali ako ih poništi kasnije, pošto je o njima već čuo, neka snosi njezinu krivnju.”"},{"v":17,"t":"To su uredbe koje je Jahve Mojsiju izdao za muža i njegovu ženu i za oca i njegovu kćer, koja, još mlada, živi u kući očevoj."}]},"31":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Iskali osvetu Izraelaca na Midjancima, a poslije toga pridružit ćeš se svojim precima.”"},{"v":3,"t":"A Mojsije reče narodu: “Opremite ljude između sebe za pohod na Midjance,"},{"v":4,"t":"da na Midjancima izvrše Jahvinu osvetu. Na vojnu opremite po jednu tisuću od svakoga izraelskog plemena!”"},{"v":5,"t":"I tako su iz izraelskih porodica - tisuću po plemenu - za vojnu skupili dvanaest tisuća."},{"v":6,"t":"Posla ih Mojsije - tisuću po plemenu - na vojnu zajedno s Pinhasom, sinom svećenika Eleazara. On je nosio posvećene stvari i trube."},{"v":7,"t":"Oni zavojuju na Midjance, kako je Jahve naredio Mojsiju, i pobiju sve muškarce."},{"v":8,"t":"Među ostalima pobili su i midjanske kraljeve: Evija, Rekema, Sura, Hura i Rebu - pet midjanskih kraljeva. Mačem pogube i Bileama, Beorova sina."},{"v":9,"t":"Odvedu tada Izraelci u ropstvo midjanske žene s njihovom djecom i svu njihovu stoku, krupnu i sitnu, i zaplijene sve njihovo blago."},{"v":10,"t":"Ognjem spale sve gradove njihove u kojima se živjeli i sva njihova naselja,"},{"v":11,"t":"a sve njihovo uzmu za plijen i pljačku, i ljude i životinje."},{"v":12,"t":"Onda u tabor na Moapskim poljanama uz Jordan, nasuprot Jerihonu, dovedu Mojsiju, svećeniku Eleazaru i svoj izraelskoj zajednici zarobljenike, plijen i pljačku."},{"v":13,"t":"Mojsije, svećenik Eleazar i svi glavari zajednice izađu im u susret izvan tabora."},{"v":14,"t":"Mojsije se razljuti na zapovjednike vojske, tisućnike i satnike, koji se bijahu vratili s toga bojnog pohoda."},{"v":15,"t":"Reče im: “Što! Na životu ste ostavili sve ženskinje!"},{"v":16,"t":"A baš su žene, po nagovoru Bileamovu, zavele Izraelce da u Peorovu slučaju istupe protiv Jahve. Tako dođe pomor na Jahvinu zajednicu."},{"v":17,"t":"Stoga svu mušku djecu pobijte! A ubijte i svaku ženu koja je poznala muškarca!"},{"v":18,"t":"A sve mlade djevojke koje nisu poznale muškarca ostavite na životu za se."},{"v":19,"t":"Vi pak proboravite izvan tabora sedam dana; svi vi koji ste koga ubili i koji ste se ubijenoga dotakli. Čistite se i vi i vaši zarobljenici trećega i sedmoga dana;"},{"v":20,"t":"očistite svu odjeću, sve mješine, sve od kostrijeti napravljeno i sve drvene predmete.”"},{"v":21,"t":"Zatim svećenik Eleazar progovori borcima koji su se vratili iz boja: “Ovo je odredba koju je izdao Jahve Mojsiju:"},{"v":22,"t":"'Zlato, srebro, bakar, gvožđe, mjed i olovo -"},{"v":23,"t":"sve što podnosi vatru - provucite kroz vatru i bit će očišćeno.' Ipak, neka se očisti i vodom očišćenja. A sve što ne podnosi vatru provucite kroz vodu."},{"v":24,"t":"Sedmoga dana operite svoju odjeću i bit ćete čisti. Poslije toga možete se vratiti u tabor.”"},{"v":25,"t":"Jahve reče Mojsiju:"},{"v":26,"t":"“Ti, svećenik Eleazar i obiteljske starješine zajednice napravite popis ratnoga plijena, ljudstva i stoke,"},{"v":27,"t":"a onda ratni plijen podijeli napola: na borce koji su išli u borbu i na svu ostalu zajednicu."},{"v":28,"t":"Od boraca koji su išli u borbu ustavi ujam za Jahvu: jednu glavu od svakih pet stotina, bilo ljudi, bilo krupnog blaga, magaradi ili sitne stoke."},{"v":29,"t":"Uzmi to od njihove polovice i podaj svećeniku Eleazaru kao podizanicu za Jahvu."},{"v":30,"t":"A od polovice što zapadne druge Izraelce uzmi po glavu od pedeset, bilo ljudi, bilo krupnog blaga, magaradi ili sitne stoke - od svih životinja - pa ih podaj levitima koji vode brigu o Jahvinu prebivalištu.”"},{"v":31,"t":"Mojsije i svećenik Eleazar učine kako je Jahve naredio Mojsiju."},{"v":32,"t":"Ratnoga je plijena bilo, osim pljačke što su vojnici napljačkali: šest stotina sedamdeset i pet tisuća grla sitne stoke,"},{"v":33,"t":"sedamdeset i dvije tisuće grla krupne stoke,"},{"v":34,"t":"šezdeset i jedna tisuća magaradi,"},{"v":35,"t":"a ljudskih duša - žena koje nisu poznale muškarca - bijaše u svemu trideset i dvije tisuće."},{"v":36,"t":"Prema tome, polovica što je dodijeljena onima koji su išli u borbu bila je: tri stotine trideset i sedam tisuća i pet stotina grla sitne stoke;"},{"v":37,"t":"ujam za Jahvu od sitne stoke šest stotina sedamdeset i pet grla;"},{"v":38,"t":"krupne je stoke bilo trideset i šest tisuća grla, a njihov ujam za Jahvu sedamdeset i dva grla;"},{"v":39,"t":"magaradi je bilo trideset tisuća i pet stotina, a njihov ujam za Jahvu šezdeset i jedno."},{"v":40,"t":"Ljudskih je duša bilo šesnaest tisuća, a njihov ujam za Jahvu trideset i dvije osobe."},{"v":41,"t":"Ujam predade Mojsije svećeniku Eleazaru za podizanicu Jahvi, kako je Jahve naredio Mojsiju."},{"v":42,"t":"A od polovice koja je zapala druge Izraelce i koju Mojsije odijeli od one što je pripala ljudima koji su se borili -"},{"v":43,"t":"dakle, polovica što je pripala zajednici iznosila je: trista trideset i sedam tisuća i pet stotina grla sitne stoke,"},{"v":44,"t":"a krupne stoke trideset i šest tisuća grla;"},{"v":45,"t":"magaradi trideset tisuća i pet stotina,"},{"v":46,"t":"a ljudskih duša šesnaest tisuća."},{"v":47,"t":"Tako, od polovice što je pripala Izraelcima Mojsije ostavi po jedno od pedeset, i od ljudstva i od stoke, te ih predade levitima koji su se brinuli o Jahvinu prebivalištu, kako je Jahve naredio Mojsiju."},{"v":48,"t":"Onda pristupiše k Mojsiju vojnički zapovjednici, tisućnici i satnici,"},{"v":49,"t":"i rekoše mu: “Tvoje sluge prebrojile su borce što bijahu pod našim zapovjedništvom i od nas nitko nije izgubljen."},{"v":50,"t":"Uz to smo donijeli svoje darove Jahvi: narukvica, orukvica, prstenja, naušnica i ogrlica - na kakvu je tko zlatninu već naišao - da se nad nama obavi obred pomirenja pred Jahvom.”"},{"v":51,"t":"Mojsije i svećenik Eleazar prime od njih to zlato, to jest sve te izrađene predmete."},{"v":52,"t":"Bilo je svega zlata što su kao svoju podizanicu Jahvi donijeli tisućnici i satnici: šesnaest tisuća sedam stotina i pedeset šekela."},{"v":53,"t":"Svaki je vojnik za se zadržao svoj plijen."},{"v":54,"t":"Tako Mojsije i svećenik Eleazar uzmu zlato od tisućnika i satnika te ga donesu u Šator sastanka na spomen Izraelcima pred Jahvom."}]},"32":{"hr":[{"v":1,"t":"Rubenovci i Gadovci imađahu mnogo, vrlo mnogo blaga. Opaze, međutim, da je zemlja jazerska i zemlja gileadska pogodna za stočarstvo."},{"v":2,"t":"Zato Gadovci i Rubenovci dođu k Mojsiju, svećeniku Eleazaru i glavarima zajednice pa reknu:"},{"v":3,"t":"“Atarot, Dibon, Jazer, Nimra, Hešbon, Eleale, Sebam, Nebo i Beon -"},{"v":4,"t":"kraj što ga Jahve osvoji pred izraelskom zajednicom - kraj je pogodan za stočarstvo; a sluge tvoje bave se stočarstvom."},{"v":5,"t":"Ako smo stekli blagonaklonost u tvojim očima”, nastave, “neka se ovaj kraj dade u posjed tvojim slugama. Ne šalji nas preko Jordana!”"},{"v":6,"t":"Mojsije odgovori Gadovcima i Rubenovcima: “Zar da vaša braća idu u rat, a vi da ostanete ovdje?"},{"v":7,"t":"Zašto odvraćate srca Izraelaca da ne prijeđu u zemlju koju im je Jahve predao?"},{"v":8,"t":"Tako su učinili i vaši očevi kad sam ih poslao iz Kadeš Barnee da izvide zemlju."},{"v":9,"t":"Popeli su se do Eškola i razgledali zemlju, ali su onda ubili srčanost u Izraelcima da ne odu u zemlju koju im je Jahve dao."},{"v":10,"t":"Onog dana Jahve planu gnjevom. Zakle se i reče:"},{"v":11,"t":"'Ljudi što su izišli iz Egipta, kojima je dvadeset ili više godina, jer me nisu vjerno slijedili, nikad neće vidjeti zemlju što sam je pod zakletvom obećao Abrahamu, Izaku i Jakovu!'"},{"v":12,"t":"Jahvu su jedino vjerno slijedili Kenižanin Kaleb, sin Jefuneov, i sin Nunov Jošua."},{"v":13,"t":"Jahve je gnjevom planuo na Izraelce pa ih je pustinjom povlačio četrdeset godina, sve dok ne pomrije sav naraštaj što je u očima Jahvinim zlo postupio."},{"v":14,"t":"A sad vi - grešni naraštaj - ustajete namjesto svojih očeva da još povećate srdžbu Jahvinu na Izraela."},{"v":15,"t":"Ako se od njega odvratite, on će još produžiti vaš boravak u pustinji; tako ćete upropastiti sav taj narod.”"},{"v":16,"t":"Onda se oni primaknu k njemu i reknu: “Mi bismo ovdje podigli torove za svoje blago i gradove za svoju nejačad,"},{"v":17,"t":"a sami ćemo pograbiti oružje i poći na čelu Izraelaca dok ih ne dovedemo na njihovo mjesto. Naša nejačad neka ostane - zbog stanovništva ove zemlje - u utvrđenim gradovima."},{"v":18,"t":"Mi se svojim kućama nećemo vraćati sve dok svaki Izraelac ne zaposjedne svoju baštinu."},{"v":19,"t":"S njima nećemo dijeliti svoje posjede s onu stranu Jordana niti dalje, jer će nas zapasti naša baština s ovu stranu, na istok od Jordana.”"},{"v":20,"t":"Mojsije im reče: “Ako tako uradite, ako pođete pred Jahvom u boj;"},{"v":21,"t":"ako vi svi naoružani prijeđete Jordan pred Jahvom dok on ne rastjera ispred sebe svoje neprijatelje:"},{"v":22,"t":"tada, kad zemlja bude pokorena Jahvi, vi ćete se moći vratiti. Tako ćete biti oslobođeni odgovornosti prema Jahvi i prema Izraelu, a ova će zemlja postati pred Jahvom vaše vlasništvo."},{"v":23,"t":"Ali ako tako ne uradite, sagriješit ćete protiv Jahve i znajte da će vas stići kazna za vaš grijeh."},{"v":24,"t":"Sazidajte, dakle, gradove za svoju nejačad i torove za svoju stoku, ali izvršite što ste obećali.”"},{"v":25,"t":"Gadovci i Rubenovci odgovore Mojsiju: “Tvoje će sluge učiniti kako gospodar naš nalaže."},{"v":26,"t":"Naša nejačad, naše žene, naša stoka i sve naše blago neka ostanu ondje u gileadskim gradovima,"},{"v":27,"t":"a tvoje sluge, svi koji su za boj sposobni, poći će pred Jahvom u boj, kako naš gospodar nalaže.”"},{"v":28,"t":"Tada za njih Mojsije izda nalog svećeniku Eleazaru, Nunovu sinu Jošui i glavarima obitelji izraelskih plemena."},{"v":29,"t":"I reče im Mojsije: “Ako Gadovci i Rubenovci, svi oni koji nose oružje, s vama prijeđu Jordan da se bore pred Jahvom i zemlja bude pokorena vama, onda im dajte gileadsku zemlju u vlasništvo."},{"v":30,"t":"Ali ako ne prijeđu naoružani s vama, neka dobiju baštinu među vama u zemlji kanaanskoj.”"},{"v":31,"t":"Nato odgovore Gadovci i Rubenovci: “Što je god Jahve rekao tvojim slugama, to ćemo učiniti."},{"v":32,"t":"Mi ćemo naoružani prijeći pred Jahvom u zemlju kanaansku, ali neka nam bude posjed naše baštine s ove strane Jordana.”"},{"v":33,"t":"I tako njima - Gadovcima, Rubenovcima i polovici plemena Manašea, sina Josipova - dadne kraljevstvo amorejskoga kralja Sihona i kraljevstvo bašanskoga kralja Oga, zemlju s gradovima u njihovim granicama, gradove okolne zemlje."},{"v":34,"t":"Gadovci sagrade: Dibon, Atarot i Aroer,"},{"v":35,"t":"Atrot Šofan, Jazer, Jogbohu,"},{"v":36,"t":"Bet Nimru i Bet Haran, utvrđene gradove i torove za stada."},{"v":37,"t":"Rubenovci sagrade: Hešbon, Eleale, Kirjatajim,"},{"v":38,"t":"Nebo, Baal Meon - nazivi su izmijenjeni - i Šibmu. Oni prozovu svojim imenima gradove koje su oni podigli."},{"v":39,"t":"Sinovi Makira, sina Manašeova, odu u Gilead, osvoje ga i protjeraju Amorejce koji bijahu ondje."},{"v":40,"t":"Mojsije preda Gilead Manašeovu sinu Makiru, i on se u njemu nastani."},{"v":41,"t":"A Manašeov sin Jair ode te zauzme njihova sela pa ih prozva “Jairova sela”."},{"v":42,"t":"Potom ode Nobah i zauzme Kenat i njegova područja te ga nazove svojim imenom “Nobah”."}]},"33":{"hr":[{"v":1,"t":"Ovo su postaje Izraelaca što ih prijeđoše kad iziđoše iz zemlje egipatske u svojim četama pod vodstvom Mojsijevim i Aronovim."},{"v":2,"t":"Na zapovijed Jahvinu Mojsije je bilježio polazne točke njihova putovanja. Ovo su njihove postaje prema njihovim polaznim točkama."},{"v":3,"t":"Iz Ramsesa krenuše u prvome mjesecu. Bio je petnaesti dan prvoga mjeseca - sutradan poslije Pashe - kad se Izraelci zaputiše uzdignutih pesnica i naočigled sviju Egipćana,"},{"v":4,"t":"dok su Egipćani pokopavali one koje je Jahve između njih pobio, to jest sve prvorođence, i tako nad njihovim božanstvima izvršio pravdu."},{"v":5,"t":"Krenu dakle Izraelci iz Ramsesa i utabore se u Sukotu."},{"v":6,"t":"Zatim odu iz Sukota i utabore se u Etamu, baš na rubu pustinje."},{"v":7,"t":"Pođu iz Etama, a onda okrenu prema Pi Hahirotu, koji se nalazi nasuprot Baal Sefona. Tabore postave pred Migdolom."},{"v":8,"t":"Krenu od Pi Hahirota i prijeđu posred mora u pustinju. Išli su tri dana pustinjom Etanom, a onda se utabore u Mari."},{"v":9,"t":"Zatim odu iz Mare i stignu u Elim. U Elimu je bilo dvanaest izvor-voda i sedamdeset palma. Tu su se utaborili."},{"v":10,"t":"Potom krenu iz Elima te se utabore uz Crveno more."},{"v":11,"t":"A otišavši od Crvenog mora, utabore se u pustinji Sinu."},{"v":12,"t":"Potom odu iz pustinje Sina i postave tabore u Dofki."},{"v":13,"t":"Otišavši iz Dofke, utabore se u Alušu."},{"v":14,"t":"Krenu iz Aluša i utabore se u Refidimu. Tu narod nije imao vode da pije."},{"v":15,"t":"Odu iz Refidima te se utabore u Sinajskoj pustinji."},{"v":16,"t":"Krenu iz Sinajske pustinje te se utabore u Kibrot Hataavi."},{"v":17,"t":"Odu iz Kibrot Hataave te se utabore u Haserotu."},{"v":18,"t":"Onda odu iz Haserota i utabore se u Ritmi."},{"v":19,"t":"Krenu iz Ritme i utabore se u Rimon Peresu."},{"v":20,"t":"Odu iz Rimon Peresa i utabore se u Libni."},{"v":21,"t":"Iz Libne odu i utabore se u Risi."},{"v":22,"t":"Odu iz Rise te se utabore u Kehelati."},{"v":23,"t":"Odu iz Kehelate i utabore se na brdu Šeferu."},{"v":24,"t":"Odu s brda Šefera i utabore se u Haradi."},{"v":25,"t":"Odu iz Harade i utabore se u Makhelotu."},{"v":26,"t":"Odu iz Makhelota te se utabore u Tahatu."},{"v":27,"t":"Odu iz Tahata i utabore se u Tarahu."},{"v":28,"t":"Iz Taraha odu i utabore se u Mitki."},{"v":29,"t":"Odu iz Mitke i utabore se u Hašmoni."},{"v":30,"t":"Iz Hašmone odu i utabore se u Moserotu."},{"v":31,"t":"Odu iz Moserota i utabore se u Bene Jaakanu."},{"v":32,"t":"Odu iz Bene Jaakana i utabore se u Hor Gidgadu."},{"v":33,"t":"Odu iz Hor Gidgada i utabore se u Jotbati."},{"v":34,"t":"Odu iz Jotbate i utabore se u Abroni."},{"v":35,"t":"Iz Abrone odu i utabore se u Esion Geberu."},{"v":36,"t":"Iz Esion Gebera odu i utabore se u pustinji Sinu, to jest u Kadešu."},{"v":37,"t":"Iz Kadeša krenu te se utabore na brdu Horu, na granici zemlje edomske."},{"v":38,"t":"Na zapovijed Jahvinu svećenik se Aron pope na brdo Hor i tu umre na prvi dan petoga mjeseca, u četrdesetoj godini nakon izlaska Izraelaca iz egipatske zemlje."},{"v":39,"t":"Aronu je bilo stotinu dvadeset i tri godine kad je preminuo na brdu Horu."},{"v":40,"t":"Aradski kralj, Kanaanac, koji je živio u kanaanskom kraju Negebu, čuo je o dolasku Izraelaca."},{"v":41,"t":"S brda Hora odu te se utabore u Salmoni."},{"v":42,"t":"Odu iz Salmone i utabore se u Punonu."},{"v":43,"t":"Odu iz Punona i utabore se u Obotu."},{"v":44,"t":"Odu iz Obota i utabore se na moapskom području u Ije-Abarimu."},{"v":45,"t":"Odu iz Ije-Abarima i utabore se u Dibon Gadu."},{"v":46,"t":"Iz Dibon Gada odu i utabore se u Almon Diblatajimu."},{"v":47,"t":"Iz Almon Diblatajima odu i utabore se na Abarimskim bregovima, pred Nebom."},{"v":48,"t":"Odu s Abarimskih bregova i utabore se na Moapskim poljanama, uz Jordan, nasuprot Jerihonu;"},{"v":49,"t":"taborovali su uz Jordan od Bet Haješimota sve do Abel Hašitima na Moapskim poljanama."},{"v":50,"t":"Na Moapskim poljanama uz Jordan, nasuprot Jerihonu, Jahve reče Mojsiju:"},{"v":51,"t":"“Ovako reci Izraelcima: 'Kad prijeđete preko Jordana u zemlju kanaansku,"},{"v":52,"t":"potjerajte ispred sebe sve stanovnike te zemlje, uništite sve njihove slike; uništite sve njihove salivene kumire i sve njihove uzvišice porušite."},{"v":53,"t":"Onda zaposjednite zemlju i u njoj se nastanite, jer sam vam je predao da je zaposjednete."},{"v":54,"t":"Zemlju razdijelite kockom među svoje rodove. Brojnijem povećajte dio, a manjem smanjite. Gdje god kocka padne, bilo za koga, neka je to njegovo, a prema otačkim plemenima dijelite im baštinu."},{"v":55,"t":"Ako stanovnike zemlje ispred sebe ne potjerate, onda će oni koje od njih na životu ostavite biti trnje u vašim očima i bodljike u vašim bokovima; dosađivat će vam u zemlji u kojoj budete živjeli"},{"v":56,"t":"i postupit ću s vama kako sam mislio postupiti s njima.'”"}]},"34":{"hr":[{"v":1,"t":"Jahve reče Mojsiju:"},{"v":2,"t":"“Izdaj Izraelcima naredbu i reci im: 'Kad uđete u kanaansku zemlju, ta će vam zemlja pripasti u baštinu, zemlja kanaanska sa svojim granicama."},{"v":3,"t":"Južna strana protezat će vam se od pustinje Sina uz Edom. Južna će vam granica početi s kraja Slanog mora na istočnoj strani."},{"v":4,"t":"Onda će vam granica skrenuti na jug, prema Akrabimskoj strmini, i nastaviti se preko Sina. Doprijet će na jugu do Kadeš Barnee; zatim će izaći prema Hasar Adaru i nastaviti se do Asmone."},{"v":5,"t":"Od Asmone granica će skrenuti prema Egipatskom potoku i izaći će na more."},{"v":6,"t":"Zapadna granica bit će vam Veliko more; neka vam je to granica prema zapadu."},{"v":7,"t":"A ovo će vam biti sjeverna granica: od Velikog mora povucite crtu na brdo Hor;"},{"v":8,"t":"s brda Hora onda potegnite crtu do ulaza u Hamat; završetak granice bit će Sedada."},{"v":9,"t":"Onda će se granica protegnuti do Zifrona i završiti u Hasar Enanu. To će vam biti sjeverna granica."},{"v":10,"t":"Za svoju istočnu granicu povucite crtu od Hasar Enana do Šefama."},{"v":11,"t":"Granica će se spuštati od Šefama do Rible, istočno od Ajina. Odande će se granica spustiti i doprijeti do istočne obale Kineretskog jezera."},{"v":12,"t":"Iza toga spustit će se granica niz Jordan da završi u Slanome moru. To će biti vaša zemlja sa svojim granicama naokolo.'”"},{"v":13,"t":"Tada Mojsije naredi Izraelcima: “To je zemlja koju ćete kockom dobiti u baštinu, a za koju je zapovjedio Jahve da je dobije devet plemena i polovica jednog plemena."},{"v":14,"t":"Jer pleme Rubenovaca prema svojim porodicama, zatim pleme Gadovaca prema svojim porodicama već primiše svoju baštinu, kao što je svoju baštinu primila i polovica plemena Manašeova."},{"v":15,"t":"Ta dva plemena i pol primila su svoje baštine s one strane Jordana, nasuprot Jerihonu, s istočne strane.”"},{"v":16,"t":"Jahve reče Mojsiju:"},{"v":17,"t":"“Ovo su imena ljudi koji će vam zemlju podijeliti: svećenik Eleazar i Nunov sin Jošua;"},{"v":18,"t":"i od svakoga plemena uzmi po jednoga glavara za razdiobu zemlje."},{"v":19,"t":"Ovo su imena tih ljudi: Kaleb, sin Jefuneov; od plemena Judina;"},{"v":20,"t":"Šemuel, sin Amihudov, od plemena Šimunova;"},{"v":21,"t":"Elidad, sin Kislonov, od plemena Benjaminova;"},{"v":22,"t":"knez Buki, sin Joglijev, od plemena Danovaca."},{"v":23,"t":"Od sinova Josipovih: knez Haniel, sin Efodov, od plemena Manašeovaca;"},{"v":24,"t":"knez Kemuel, sin Šiftanov, od plemena Efrajimovaca;"},{"v":25,"t":"knez Elisafan, sin Parnakov, od plemena Zebulunovaca;"},{"v":26,"t":"knez Paltiel, sin Azanov, od plemena Jisakarovaca;"},{"v":27,"t":"knez Ahihud, sin Šelomijev, od plemena Ašerovaca;"},{"v":28,"t":"knez Pedahel, sin Amihudov, od plemena Naftalijevaca.”"},{"v":29,"t":"To su oni kojima je Jahve naložio da Izraelcima izdijele baštinu u zemlji kanaanskoj."}]},"35":{"hr":[{"v":1,"t":"Reče Jahve Mojsiju na Moapskim poljanama kod Jordana, nasuprot Jerihonu:"},{"v":2,"t":"“Naredi Izraelcima da ustupe levitima od baštine koju posjeduju gradove gdje će stanovati i pašnjake oko gradova. To dajte levitima."},{"v":3,"t":"Neka gradovi budu njima za stanovanje, a okolni pašnjaci neka budu za njihova goveda, njihovo blago i sve njihove životinje."},{"v":4,"t":"Pašnjaci uz gradove koje ustupite levitima neka zahvate od gradskih zidina van do tisuću lakata naokolo."},{"v":5,"t":"Izmjerite od grada van dvije tisuće lakata s istočne strane, dvije tisuće lakata s južne strane, dvije tisuće lakata sa zapadne strane i sa sjeverne strane dvije tisuće lakata, tako da grad bude u sredini. To neka im budu gradski pašnjaci."},{"v":6,"t":"Od gradova koje budete dali levitima šest će ih biti gradovi-utočišta, koje ćete ustupiti da ubojica može tamo pobjeći. Ovima dodajte još četrdeset i dva grada."},{"v":7,"t":"Tako će svih gradova koje ustupite levitima biti četrdeset i osam gradova s njihovim pašnjacima."},{"v":8,"t":"A gradove koje budete izdvajali od vlasništva Izraelaca, od onih koji ih imaju mnogo uzmite više, a manje od onih koji imaju malo. Neka svatko ustupi gradove levitima prema omjeru baštine koju bude primio.”"},{"v":9,"t":"Nadalje reče Jahve Mojsiju:"},{"v":10,"t":"“Govori Izraelcima i reci im: 'Kad prijeđete preko Jordana u zemlju kanaansku,"},{"v":11,"t":"označite sebi gradove koji će vam služiti kao gradovi-utočišta, kamo može pobjeći ubojica koji nehotice koga ubije."},{"v":12,"t":"Ti gradovi neka vam budu utočište od osvetnika, tako da ubojica ne moradne poginuti dok ne stane na sud pred zajednicu."},{"v":13,"t":"Od gradova koje ustupite bit će vam šest gradova za utočište."},{"v":14,"t":"Dodijelite tri grada s onu stranu Jordana, a tri grada u zemlji kanaanskoj. Neka to budu gradovi-utočišta."},{"v":15,"t":"Tih šest gradova neka budu za utočište kako Izraelcima tako i strancu i došljaku koji među njima borave, kamo može pobjeći tko god ubije koga nehotice."},{"v":16,"t":"Ali ako tko udari koga gvozdenim predmetom te ga usmrti, to je onda ubojica. Ubojica mora glavom platiti."},{"v":17,"t":"Udari li ga iz ruke kamenom od kojega čovjek može poginuti i zbilja pogine, to je opet ubojica. Ubojica mora glavom platiti."},{"v":18,"t":"Ili ako ga udari iz ruke kakvim drvenim predmetom od kojega može umrijeti i zbilja umre, i to je ubojica. Ubojica mora glavom platiti."},{"v":19,"t":"Krvni osvetnik mora sam ubojicu usmrtiti. Kad ga sretne, neka ga ubije."},{"v":20,"t":"Nadalje, ako tko koga gurne iz mržnje ili na nj nešto baci namjerno te ga usmrti,"},{"v":21,"t":"ili ga udari rukom iz zlobe te udareni umre, napadač mora zaglaviti - on je ubojica. Krvni osvetnik neka ubojicu ubije čim ga sretne."},{"v":22,"t":"No gurne li ga slučajno, ne iz neprijateljstva, ili nešto na nj baci, ali ne iz zasjede,"},{"v":23,"t":"ili iz nepažnje na njega obori kakav kamen od kojega čovjek može poginuti te ga usmrti, a nije mu bio neprijatelj niti mu je zlo želio -"},{"v":24,"t":"tada neka zajednica prosudi između ubojice i krvnog osvetnika prema ovim pravilima:"},{"v":25,"t":"Zajednica mora izbaviti ubojicu iz ruku krvnog osvetnika; onda neka ga zajednica vrati u grad-utočište kamo je pobjegao; tu neka on ostane do smrti velikoga svećenika koji je bio pomazan svetim uljem."},{"v":26,"t":"Ali ako ubojica ikad izađe izvan granice utočišta kamo je pobjegao,"},{"v":27,"t":"pa na nj nabasa krvni osvetnik izvan granica njegova grada-utočišta te krvni osvetnik ubije ubojicu, to mu se ne računa u krvoproliće,"},{"v":28,"t":"jer ubojica mora ostati u gradu-utočištu do smrti velikoga svećenika. A poslije smrti velikoga svećenika može se vratiti na svoj posjed."},{"v":29,"t":"Neka vam takvi budu sudbeni postupci od naraštaja do naraštaja svuda gdje budete boravili."},{"v":30,"t":"Za svako ubojstvo čovjeka kazna smrti nad ubojicom može se izvršiti na dokaz svjedoka. Nitko se ne može smrću kazniti na dokaz samo jednog svjedoka."},{"v":31,"t":"Ne smijete primati otkupnine za život ubojice koji je zaslužio smrt: on mora umrijeti."},{"v":32,"t":"Niti smijete primati otkupnine od bilo koga koji, pošto je pobjegao u svoj grad-utočište, hoće da se vrati i da živi na svome tlu prije smrti velikoga svećenika."},{"v":33,"t":"Nemojte oskvrnjivati zemlje u kojoj živite. A krvoprolićem zemlja se oskvrnjuje. Za zemlju na kojoj je krv prolivena pomirenje se ne može pribaviti, osim krvlju onoga koji ju je prolio."},{"v":34,"t":"Ne smije se obeščašćivati zemlja u kojoj živite i usred koje ja boravim, jer ja, Jahve, prebivam među sinovima Izraelovim.'”"}]},"36":{"hr":[{"v":1,"t":"Tada pristupe obiteljski glavari od roda sinova Gileada, sina Makirova, sina Manašeova, jednoga roda Josipovih sinova, te pred Mojsijem i starješinama, glavarima obitelji,"},{"v":2,"t":"reknu: “Jahve je naredio našemu gospodaru da kockom dade ovu zemlju u baštinu Izraelcima; nadalje, našem je gospodaru naredio Jahve da baštinu našega brata Selofhada dade njegovim kćerima."},{"v":3,"t":"Ali ako se one udaju za koga iz drugog izraelskoga plemena, onda će njihova baština biti otrgnuta od naše djedovske baštine i biti priključena baštini plemena kojemu one pripadnu. Tako će se okrnjiti baština koja kockom pripadne nama."},{"v":4,"t":"A kada nastupi jubilej Izraelcima, baština će se tih žena dodati baštini plemena kojemu pripadnu. Tako će njihova baština biti oduzeta od baštine našega pradjedovskog plemena.”"},{"v":5,"t":"I po zapovijedi Jahvinoj Mojsije naredi Izraelcima: “Pleme Josipovih sinova pravo govori."},{"v":6,"t":"Ovo naređuje Jahve za Selofhadove kćeri: Neka se one udaju za onoga koji im se učini dobar, samo neka se udaju u rod svoga očinskoga plemena."},{"v":7,"t":"Baština Izraelaca ne smije se prenositi iz jednoga plemena u drugo; i svaki Izraelac mora ostati privezan uz pradjedovsku baštinu svoga plemena."},{"v":8,"t":"Zato se svaka djevojka koja steče baštinu u izraelskim plemenima mora udati za nekoga u plemenu kojemu pripada rod joj očev, tako da bi svaki Izraelac sačuvao baštinu svoga oca."},{"v":9,"t":"Tako se baština neće prenositi iz jednoga plemena u drugo, nego će svako izraelsko pleme prianjati uza svoju baštinu.”"},{"v":10,"t":"Kako je Jahve Mojsiju naredio, tako su i učinile kćeri Selofhadove:"},{"v":11,"t":"Mahla, Tirsa, Hogla, Milka i Noa, kćeri Selofhadove, udaše se za sinove svojih stričeva."},{"v":12,"t":"Kako su se udale u rod potomstva Manašea, Josipova sina, njihova je baština ostala u plemenu kojemu pripadaše rod im očev."},{"v":13,"t":"To su zapovijedi i zakoni koje je Jahve preko Mojsija izdao Izraelcima na Moapskim poljanama uz Jordan, nasuprot Jerihonu."}]}},"DEU":{"1":{"hr":[{"v":1,"t":"Ovo su riječi što ih je Mojsije upravio svemu Izraelu s onu stranu Jordana - u pustinji, u Arabi nasuprot Sufu, između Parana i Tofela, Labana, Hazerota i Di Zahaba -"},{"v":2,"t":"od Horeba do Kadeš Barnee, Seirskom gorom, jedanaest dana hoda."},{"v":3,"t":"Bilo je to godine četrdesete, prvog dana mjeseca jedanaestoga, kad Mojsije reče Izraelcima sve što mu je Jahve za njih naređivao."},{"v":4,"t":"Pošto je porazio amorejskoga kralja Sihona, koji je živio u Hešbonu, i bašanskoga kralja Oga, koji je živio u Aštarotu i Edreju,"},{"v":5,"t":"dakle s onu stranu Jordana, u zemlji moapskoj, poče Mojsije razlagati ovaj Zakon. Govoraše on:"},{"v":6,"t":"“Jahve, Bog naš, reče nam na Horebu: 'Dosta ste boravili na ovome brdu."},{"v":7,"t":"Krenite na put! Idite u gorski kraj Amorejaca i svih njihovih susjeda, u Arabu, u Gorje, u Šefelu i u Negeb, na morsku obalu, u zemlju kanaansku i u Libanon, sve do Velike rijeke, rijeke Eufrata."},{"v":8,"t":"Eto, pred vas stavljam ovu zemlju. Idite, dakle, i zauzmite zemlju za koju se Jahve zakle ocima vašim, Abrahamu, Izaku i Jakovu, da će je dati njima i njihovu potomstvu poslije njih.'"},{"v":9,"t":"Tada sam vam rekao: 'Ne mogu vas voditi sam."},{"v":10,"t":"Jahve, Bog vaš, toliko vas je razmnožio da vas danas ima kao zvijezda na nebu."},{"v":11,"t":"Neka vas Jahve, Bog vaših otaca, umnoži još tisuću puta! Neka vas blagoslivlja kako vam je obećao!"},{"v":12,"t":"Ali kako bih ja sam mogao nositi vaš teret, vaše breme i vaše sporove?"},{"v":13,"t":"Izaberite stoga iz svojih plemena ljude pametne, iskusne i ugledne da vam ih postavim za poglavare.'"},{"v":14,"t":"Vi ste mi odgovorili: 'Dobro je što predlažeš.'"},{"v":15,"t":"Zato sam uzeo prvake iz vaših plemena, ljude pametne i ugledne, te ih postavio za poglavare: tisućnike, stotnike, pedesetnike, desetnike i vaše plemenske nadglednike."},{"v":16,"t":"U to isto vrijeme naložio sam i vašim sucima: 'Saslušajte svoju braću; sudite pravedno između čovjeka i njegova brata ili pridošlice."},{"v":17,"t":"U suđenju nemojte biti pristrani; saslušavajte maloga kao i velikoga. Ne bojte se nikoga! TÓa sud je Božji! Ako vam koji slučaj bude pretežak, iznesite ga meni, da ga ja razvidim.'"},{"v":18,"t":"Tako sam vam onda naložio sve što vam je činiti."},{"v":19,"t":"Krenusmo iz Horeba i, na putu u gorske krajeve Amorejaca, kako nam je naredio Jahve, Bog naš, prijeđosmo svu onu veliku i strašnu pustinju koju ste vidjeli. Stigosmo u Kadeš Barneu."},{"v":20,"t":"Tada vam rekoh: 'Došli ste u gorski kraj Amorejaca, koji nam Jahve, Bog naš, daje."},{"v":21,"t":"Eto, Jahve, Bog tvoj, stavio je preda te tu zemlju. Ustaj! Zaposjedni je, kako ti je rekao Jahve, Bog otaca tvojih. Ne boj se! Ne strahuj!'"},{"v":22,"t":"Svi ste onda došli k meni i rekli: 'Pošaljimo pred sobom ljude da izvide zemlju i jave nam o putu kojim ćemo ići i o gradovima u koje ćemo doći.'"},{"v":23,"t":"Svidje mi se što rekoste. Zato uzeh dvanaest ljudi između vas, po jednoga iz svakog plemena."},{"v":24,"t":"Krenuli su na pogorje, stigli do Eškolske doline te izvidjeli kraj."},{"v":25,"t":"I nabraše plodova one zemlje, donesoše ih k nama i javiše: 'Zemlja koju nam daje Jahve, Bog naš, dobra je.'"},{"v":26,"t":"Ali vi niste htjeli onamo; pobunili ste se protiv naredbe Jahve, Boga svoga."},{"v":27,"t":"Rogoborili ste u svojim šatorima i govorili: 'U svojoj mržnji na nas Jahve nas je izveo iz zemlje egipatske da nas preda u ruke Amorejaca, kako bi nas posve uništili."},{"v":28,"t":"Kamo da idemo? Naša su braća ubila u nama srčanost kad rekoše: Narod je i veći i jači nego mi; gradovi su veliki, i zidine im sežu do nebesa. A vidjeli smo ondje i Anakovce.'"},{"v":29,"t":"'Ne bojte se!' - rekoh vam. - 'Ne plašite ih se!"},{"v":30,"t":"Jahve, Bog vaš, koji ide pred vama, borit će se za vas kako je to učinio na vaše oči u Egiptu.'"},{"v":31,"t":"A vidio si, uostalom, i u pustinji, gdje te Jahve, Bog tvoj, cijeloga puta što ste ga prevalili dok ste stigli do ovoga mjesta, nosio kao što čovjek nosi svoga sinčića."},{"v":32,"t":"Ali, unatoč tome, vi niste imali pouzdanja u Jahvu, Boga svoga,"},{"v":33,"t":"u onoga koji je na putu išao pred vama da vam potraži mjesto za taborovanje - u ognju obnoć da vam osvijetli put kojim ćete ići, a obdan u oblaku."},{"v":34,"t":"Jahve ču graju vašu i zakle se u svojoj srdžbi:"},{"v":35,"t":"'Ni jedan jedini od ovih ljudi, od ovoga opakog naraštaja, neće vidjeti ove dobre zemlje za koju sam se zakleo da ću je dati vašim ocima."},{"v":36,"t":"Izuzimam Kaleba, sina Jefuneova. On će je vidjeti; njemu i njegovim potomcima dat ću zemlju kojom je išao, jer je vjerno slijedio Jahvu.'"},{"v":37,"t":"Zbog vas se Jahve i na mene razljutio te mi rekao: 'Ni ti onamo nećeš ući."},{"v":38,"t":"Ući će onamo Jošua, sin Nunov, koji te služi. Njega ti osokoli, jer će on uvesti Izraela u posjed."},{"v":39,"t":"A i vaši mališani, o kojima rekoste da će postati roblje, sinovi vaši koji još ne znaju razlikovati dobro i zlo, oni će u nju ući; njima ću je u posjed dati."},{"v":40,"t":"A vi se okrenite i zaputite u pustinju, prema Crvenome moru!'"},{"v":41,"t":"Vi ste mi tada odgovorili riječima: 'Sagriješili smo protiv Jahve. Poći ćemo gore i boriti se kako nam je Jahve, Bog naš, zapovjedio.' Svaki od vas dohvati svoje oružje i nepromišljeno pođe gore u brda."},{"v":42,"t":"Onda mi Jahve reče: 'Kaži im: Ne idite gore i ne stupajte u borbu da vas ne poraze vaši neprijatelji jer ja nisam među vama.'"},{"v":43,"t":"Tako sam vam i govorio, ali niste poslušali. Oprli ste se zapovijedi Jahvinoj i, puni drskosti, krenuli u brda."},{"v":44,"t":"Ali Amorejci, koji žive u onome gorju, udariše na vas, pognaše vas, za vama se natisnuše kao pčele te su vas tukli od Seira do Horme."},{"v":45,"t":"Vrativši se, plakali ste pred Jahvom, ali Jahve nije slušao vašega jauka niti je okrenuo svoga uha k vama."},{"v":46,"t":"U Kadešu vam valjade ostati dugo vremena, onoliko koliko ste već ostali."}]},"2":{"hr":[{"v":1,"t":"Onda se okrenusmo i pođosmo u pustinju prema Crvenome moru, kako mi je Jahve naredio. Dugo smo se vrtjeli oko gore Seira."},{"v":2,"t":"I reče mi Jahve:"},{"v":3,"t":"'Dosta ste se vrtjeli oko ovoga brda. Okrenite prema sjeveru!'"},{"v":4,"t":"I narodu naloži ovako: 'Sad ćete proći preko područja svoje braće, potomaka Ezavovih, koji žive u Seiru. Oni se vas boje, ali vi dobro pripazite;"},{"v":5,"t":"s njima ne zamećite boja jer vam neću dati ni stope njihove zemlje: goru Seir predao sam Ezavu u vlasništvo."},{"v":6,"t":"Hranu od njih kupujte za novac da imate što jesti; i vodu za piće kupujte od njih za novac.'"},{"v":7,"t":"Ta Jahve te, Bog tvoj, blagoslovio u svim djelima tvojih ruku; on je bdio nad tvojim putovanjem onom velikom pustinjom; ovih četrdeset godina Jahve, Bog tvoj, bijaše s tobom i ništa ti nije nedostajalo."},{"v":8,"t":"Tako smo svoju braću, potomke Ezavove što žive u Seiru, zaobišli putem što vodi u Arabu, Elat i Esjon Geber, a onda udarismo prema Moapskoj pustinji."},{"v":9,"t":"Tada mi zapovjedi Jahve: 'Nemoj uznemirivati Moapce niti s njima zameći boja, jer ništa od njihove zemlje neću dati u tvoje vlasništvo: Lotovim sinovima predao sam Ar u posjed.'"},{"v":10,"t":"Prije su ondje živjeli Emijci. Bio je to moćan narod i brojan; krupna stasa kao i Anakovci."},{"v":11,"t":"Poput Anakovaca, i njih smatraju Refaimcima, ali ih Moapci nazivaju Emijcima."},{"v":12,"t":"Isto su tako u Seiru živjeli prije Horijci, ali su ih Ezavovi potomci izvlastili, istrijebili ih i naselili se na njihovo, kako je, uostalom, učinio Izrael sa zemljom - baštinom svojom - koju mu je Jahve predao."},{"v":13,"t":"'A sada ustanite i prijeđite preko potoka Zereda!' I prijeđosmo potok Zered."},{"v":14,"t":"Vrijeme što smo išli od Kadeš Barnee pa dok smo prešli preko potoka Zereda iznosilo je trideset i osam godina - sve dok nije izumro iz tabora sav onaj naraštaj ljudi sposobnih za borbu, kako im se Jahve i zakleo."},{"v":15,"t":"I zbilja! Ruka Jahvina bila je protiv njih: istrebljivala ih je isred tabora dok ih nije nestalo."},{"v":16,"t":"I tako, kad je smrt istrijebila iz naroda sve ljude sposobne za borbu,"},{"v":17,"t":"reče mi Jahve:"},{"v":18,"t":"'Danas prelaziš moapsku zemlju Ar."},{"v":19,"t":"A onda ćeš se približiti Amoncima. Nemoj ih uznemirivati niti s njima zameći boja. Ništa, naime, od zemlje Amonaca neću ustupiti tebi u vlasništvo jer sam je već predao u posjed Lotovim potomcima.'"},{"v":20,"t":"I nju smatraju refaimskom zemljom. U njoj su prije živjeli Refaimci, koje Amonci zovu Zamzumijcima."},{"v":21,"t":"Bio je to narod moćan i brojan; krupna stasa kao i Anakovci. No Jahve ih uništi pred Amoncima - koji ih izvlastiše i naseliše se na njihovo,"},{"v":22,"t":"kako je, uostalom, učinio i potomcima Ezavovim, koji su nastanjeni u Seiru, kad je pred njima uništio Horijce, koje su oni otjerali s posjeda i do danas žive na njihovim mjestima."},{"v":23,"t":"I Avijce, koji su živjeli po zaseocima sve do Gaze, istrijebiše Kaftorci koji su došli iz Kaftora te se naseliše na njihovo mjesto."},{"v":24,"t":"'Ustajte! Na put krenite i prijeđite preko potoka Arnona. U ruke ti, eto, predajem Amorejca Sihona, kralja hešbonskoga, i njegovu zemlju. Počni s osvajanjem; izazovi ga na boj!"},{"v":25,"t":"Od danas počinjem ugoniti strah i trepet pred tobom u narode koji su pod svim nebesima, tako da će strepiti i tresti se pred tobom kad god čuju glas o tebi.'"},{"v":26,"t":"Tada sam iz pustinje Kedmot uputio glasnike kralju hešbonskom Sihonu s miroljubivim riječima:"},{"v":27,"t":"'Pusti da prođem preko tvoje zemlje. Samo ću proći putem, ne skrećući ni desno ni lijevo."},{"v":28,"t":"Hranu mi prodavaj za novac da mogu jesti; i vodu za piće davaj mi za novac. Pusti me samo da pješice prođem,"},{"v":29,"t":"da prijeđem preko Jordana u zemlju koju nam daje Jahve, Bog naš - kao što su mi dopustili potomci Ezavovi, nastanjeni u Seiru, i Moapci, što žive u Aru.'"},{"v":30,"t":"Ali hešbonski kralj Sihon ne htjede nas pustiti preko svoga; jer Jahve, Bog tvoj, duh mu zaslijepi a srce otvrdnu, da ga preda u tvoje šake, gdje je i danas."},{"v":31,"t":"Tada mi reče Jahve: 'Eto sam počeo da ti izručujem Sihona i njegovu zemlju. Počni osvajanje da mu zemljom zagospodariš.'"},{"v":32,"t":"Kod Jahasa presrete nas Sihon."},{"v":33,"t":"Navali on i sav njegov narod. Ali Jahve, Bog naš, predade nam ga, tako da potukosmo njega, njegove sinove i sav njegov narod."},{"v":34,"t":"Tada osvojismo sve njegove gradove i prokletstvom udarismo sve gradove s ljudima, ženama i djecom, ništa ne štedeći,"},{"v":35,"t":"izuzev stoke, koju uzesmo kao plijen, skupa s plijenom iz gradova što smo ih osvojili."},{"v":36,"t":"Od Aroera, koji se nalazi na obali potoka Arnona, i od grada koji je u njegovoj dolini pa do Gileada nije bilo grada koji bi nam odolio: sve nam ih je Jahve, Bog naš, predao."},{"v":37,"t":"Jedino se nisi primicao zemlji Amonaca, kraju uz potok Jabok, i gradovima u pogorju, kako je Jahve, Bog naš, odredio."}]},"3":{"hr":[{"v":1,"t":"Tada se okrenusmo i pođosmo prema Bašanu. Presrete nas bašanski kralj Og sa svim svojim narodom i nametnu nam boj kod Edreja."},{"v":2,"t":"Tada mi Jahve reče: 'Ne boj ga se! TÓa u tvoje sam ruke predao njega, sav njegov narod i njegovu zemlju. Učini s njim kako si učinio sa Sihonom, kraljem amorejskim, koji je živio u Hešbonu.'"},{"v":3,"t":"Tako je Jahve, Bog naš, u ruke naše predao i bašanskoga kralja Oga sa svim njegovim narodom. Tukli smo ga tako da mu nitko na životu nije ostao."},{"v":4,"t":"Osvojili smo tada sve njegove gradove. Nije bilo grada koji im nismo oteli - šezdeset gradova, zapravo svu argopsku krajinu, Ogovo kraljevstvo u Bašanu."},{"v":5,"t":"Svi su oni gradovi bili utvrđeni visokim zidinama, vratima i prijevornicama. Uz njih je bilo veoma mnogo otvorenih zaselaka."},{"v":6,"t":"Udarismo ih prokletstvom - kako smo učinili i sa Sihonom, kraljem hešbonskim - zatrvši svaki grad, ljude, žene i djecu."},{"v":7,"t":"A svu stoku i plijen po tim gradovima zadržasmo za se."},{"v":8,"t":"Tako smo u ono vrijeme iz ruku dvaju amorejskih kraljeva uzeli zemlju što se nalazi s onu stranu Jordana, od potoka Arnona do brda Hermona ("},{"v":9,"t":"Sidonci zovu Hermon Sirjon, a Amorejci ga zovu Senir):"},{"v":10,"t":"sve gradove po Visoravni, sav Gilead i sav Bašan, sve do Salke i Edreja - gradove Ogova kraljevstva u Bašanu. ("},{"v":11,"t":"Bašanski kralj Og jedini je od preostalih Refaimovaca. Krevet njegov, odar od željeza, još se nalazi u Rabi, gradu sinova Amonovih: deset je lakata - običnih lakata - dug, a četiri lakta širok.)"},{"v":12,"t":"To je, dakle, bila zemlja koju smo zauzeli u ono vrijeme, počev od Aroera, koji je na potoku Arnonu. Polovicu gileadskog pogorja s njegovim gradovima dao sam Rubenovcima i Gadovcima."},{"v":13,"t":"Ostatak Gileada i sav Bašan, Ogovo kraljevstvo, dodijelio sam polovini Manašeova plemena. (Sva argopska krajina i sav Bašan zove se zemlja refaimska."},{"v":14,"t":"Manašeov sin Jair zauzeo je svu argopsku krajinu do međe Gešurovaca i Maakinovaca. On ta mjesta bašanska nazva svojim imenom, pa se još i danas zovu Jairova Sela.)"},{"v":15,"t":"Makiru sam dodijelio Gilead."},{"v":16,"t":"Rubenovcima i Gadovcima dao sam od Gileada do potoka Arnona - sredina potoka jest međa - i do potoka Jaboka, amonske granice."},{"v":17,"t":"A granicom su služile Araba i Jordan od Kinereta do mora uz Arabu - Slanog mora - na podnožju obronaka Pisge prema istoku."},{"v":18,"t":"U ono vam vrijeme naredih: 'Jahve, Bog vaš, daje vam ovu zemlju u posjed. Svi vi koji ste od boja pođite naoružani pred svojom braćom Izraelcima."},{"v":19,"t":"Jedino žene vaše, djeca vaša i stoka vaša - znam da imate mnogo stoke - neka ostanu u vašim gradovima što vam ih dodijelih"},{"v":20,"t":"dokle Jahve ne dadne miran boravak i vašoj braći kao i vama; tako da i oni zauzmu zemlju što im je Jahve, Bog vaš, daje s onu stranu Jordana. Istom onda neka se svaki od vas vrati na posjed što sam vam ga dodijelio.'"},{"v":21,"t":"U ono sam vrijeme naredio Jošui: 'Svojim si očima vidio što je sve Jahve, Bog vaš, učinio onoj dvojici kraljeva. Tako će Jahve učiniti sa svim kraljevstvima preko kojih budeš prelazio."},{"v":22,"t":"Ne bojte se njih! TÓa Jahve, Bog vaš, bori se za vas.'"},{"v":23,"t":"Tada zamolih milost u Jahve:"},{"v":24,"t":"'Gospodine moj, Jahve! Ti si počeo pokazivati svome sluzi svoju veličajnost i svoju moć. TÓa koji bog, na nebu ili na zemlji, može izvesti takva djela i čudesa kao što su tvoja!"},{"v":25,"t":"Dopusti mi da odem onamo i pogledam onu blaženu zemlju preko Jordana, onaj krasni gorski kraj i Libanon!'"},{"v":26,"t":"Ali je Jahve, zbog vas, bio na me ljut, pa me nije uslišao. 'Dosta', reče mi Jahve, 'ne govori mi više o tom!"},{"v":27,"t":"Popni se na vrhunac Pisge i upri oči svoje na zapad, sjever, jug i istok. Razmotri dobro očima svojim, jer preko Jordana nećeš prijeći."},{"v":28,"t":"Uputi Jošuu, osokoli ga i ohrabri! On neka ide na čelu ovoga naroda; neka ih on uvede u posjed zemlje koju vidiš.'"},{"v":29,"t":"Tako smo ostali u toj dolini kraj Bet Peora.”"}]},"4":{"hr":[{"v":1,"t":"“A sada, Izraele, poslušaj zakone i uredbe kojima vas učim da biste ih vršili i tako poživjeli te unišli i zaposjeli zemlju koju vam daje Jahve, Bog otaca vaših."},{"v":2,"t":"Niti što nadodajite onome što vam zapovijedam niti što od toga oduzimljite; vršite zapovijedi Jahve, Boga svoga, što vam ih dajem."},{"v":3,"t":"Vidjeli ste svojim očima što je Jahve učinio s Baal Peorom: jer Jahve, Bog tvoj, iskorijenio je iz tvoje sredine svakoga koji je slijedio Baal Peora."},{"v":4,"t":"A svi vi koji se čvrsto držite Jahve, Boga svoga, živi ste i danas."},{"v":5,"t":"Ja sam vas, eto, poučio o zakonima i uredbama, kako mi je Jahve, Bog moj, naredio da ih vršite u zemlji u koju idete da je zaposjednete."},{"v":6,"t":"Držite ih i vršite: to će u očima naroda biti vaša mudrost i vaša razboritost. Kad oni čuju za sve ove zakone, reći će: 'Samo je jedan narod mudar i pametan, a to je ovaj veliki narod.'"},{"v":7,"t":"Jer koji je to narod tako velik da bi mu bogovi bili tako blizu kao što je Jahve, Bog naš, nama kad god ga zazovemo?"},{"v":8,"t":"Koji je to narod tako velik da bi imao zakone i uredbe pravedne kao što je sav ovaj Zakon koji vam ja danas iznosim?"},{"v":9,"t":"Zato pazi i dobro se čuvaj da ne zaboraviš događaje što si ih svojim očima vidio; neka ti ne iščeznu iz srca ni jednoga dana tvoga života; naprotiv, pouči o njima svoje sinove i sinove svojih sinova."},{"v":10,"t":"Onog dana kad si stajao na Horebu pred Jahvom, Bogom svojim, Jahve mi je rekao: 'Skupi mi narod! Hoću da čuju moje riječi, da me se nauče bojati sve vrijeme što budu živjeli na zemlji te da o njima pouče i svoju djecu.'"},{"v":11,"t":"Vi ste se onda primakli i stali pod brdo. S usplamtjeloga brda plamen je sukljao do sred neba zamračena tmastim oblakom."},{"v":12,"t":"Isred ognja Jahve je govorio vama; čuli ste zvuk riječi, ali lika niste nazreli - ništa osim glasa."},{"v":13,"t":"Objavio vam je svoj Savez i naložio vam da ga vršite - Deset zapovijedi, što ih ispisa na dvije kamene ploče."},{"v":14,"t":"A meni je Jahve naredio da vas poučim o zakonima i uredbama što ćete ih vršiti u zemlji u koju odlazite da je zaposjednete."},{"v":15,"t":"Pazite dobro! Onoga dana kad vam je Jahve, Bog vaš, govorio isred ognja na Horebu, niste vidjeli nikakva lika,"},{"v":16,"t":"da se ne biste pokvarili te da ne biste pravili sebi kakva klesana lika, kipa muškoga ili ženskoga obličja,"},{"v":17,"t":"ni obličja kakve životinje što je na zemlji, ni obličja kakve ptice što pod nebom lijeta,"},{"v":18,"t":"ni obličja bilo čega što po zemlji gmiže, ni obličja kakve ribe što je u vodi pod zemljom"},{"v":19,"t":"i da se ne bi, kad digneš svoje oči prema nebu te vidiš sunce, mjesec i zvijezde - svu nebesku vojsku - dao zavesti da im se klanjaš i da im iskazuješ štovanje. Njih je Jahve, Bog tvoj, dao svim narodima, svugdje pod nebom."},{"v":20,"t":"A vas je uzeo Jahve i izveo vas iz Egipta - iz one peći ražarene - da postanete narod njegove baštine, to što ste danas."},{"v":21,"t":"Ali se zbog vas Jahve na me razljutio i zakleo da ja neću prijeći preko Jordana i unići u blaženu zemlju koju ti Jahve, Bog tvoj, daje u baštinu."},{"v":22,"t":"Tako, ja ću umrijeti u ovoj zemlji; ja preko Jordana neću prijeći. A vi ćete prijeći i zaposjesti onu krasnu zemlju."},{"v":23,"t":"Zato pazite da ne zaboravljate Saveza što ga je Jahve, Bog vaš, sklopio s vama te sebi ne pravite klesanih likova bilo čega što je Jahve, Bog tvoj, zabranio."},{"v":24,"t":"Jer Jahve, Bog tvoj, oganj je što proždire; on je Bog ljubomoran."},{"v":25,"t":"Kad budete izrodili djecu i unučad i budete dulje u onoj zemlji proboravili, a pokvarite se praveći sebi bilo kakve klesane likove i čineći zlo u očima Jahve, Boga svojega, tako da ga na srdžbu izazovete,"},{"v":26,"t":"znajte - uzimam za svjedoke protiv vas nebesa i zemlju - da će vas brzo nestati sa zemlje u koju idete preko Jordana da je zaposjednete: nećete dugo u njoj živjeti nego ćete biti iskorijenjeni."},{"v":27,"t":"Jahve će vas raspršiti po narodima i ostat će vas samo malen broj među narodima među koje vas Jahve odvede."},{"v":28,"t":"Ondje ćete se klanjati bogovima što su ih ljudske ruke načinile od drveta i kamena, bogovima koji ne mogu ni vidjeti ni čuti, ni jesti ni mirisati."},{"v":29,"t":"Ondje ćeš tražiti Jahvu, Boga svoga. I naći ćeš ga ako ga budeš tražio svim srcem svojim i svom dušom svojom."},{"v":30,"t":"U nevolji tvojoj snaći će te sve to, ali u posljednje vrijeme ti ćeš se obratiti Jahvi, Bogu svomu, i poslušati njegov glas."},{"v":31,"t":"TÓa Jahve, Bog tvoj, Bog je milosrdan; neće te on zapustiti ni upropastiti niti će zaboraviti Saveza što ga je pod zakletvom sklopio s ocima tvojim."},{"v":32,"t":"Ispitaj samo prijašnja vremena što su protekla prije tebe, sve otkad je Bog stvorio čovjeka na zemlji: je li ikad, s jednoga kraja nebesa do drugoga, bilo ovako veličanstvena događaja? Je li se što takvo čulo?"},{"v":33,"t":"Je li ikad koji narod čuo glas Boga gdje govori isred ognja kao što si ti čuo i na životu ostao?"},{"v":34,"t":"Ili, pokuša li koji bog da ode i uzme sebi jedan narod isred drugog naroda kušnjama, znakovima, čudesima i ratom, jakom rukom i ispruženom mišicom, uza silne strahote, kao što je sve to, na vaše oči, učinio za vas Jahve, Bog vaš, u Egiptu?"},{"v":35,"t":"Tebi je to pokazano da znaš da je Jahve pravi Bog i da nema drugoga uz njega."},{"v":36,"t":"S neba ti se oglasio svojim glasom da te pouči; dopustio ti je da vidiš njegov veliki oganj na zemlji; i isred ognja čuo si njegove riječi."},{"v":37,"t":"Zbog toga što je ljubio očeve tvoje, izabrao je poslije njih njihovo potomstvo; on, glavom, izveo te iz Egipta svojom silnom moći;"},{"v":38,"t":"ispred tebe rastjerao je narode, i brojnije i jače od tebe, da te dovede u njihovu zemlju i preda je tebi u baštinu, kao što je i danas."},{"v":39,"t":"Danas, dakle, spoznaj i zasadi u svoje srce: Jahve je Bog gore na nebu i ovdje na zemlji - drugoga nema."},{"v":40,"t":"Drži njegove zakone i njegove zapovijedi koje ti dajem danas da dobro bude tebi i tvojoj djeci poslije tebe; da dugo poživiš na zemlji koju ti Jahve, Bog tvoj, daje zauvijek.”"},{"v":41,"t":"Tada Mojsije izabra tri grada preko Jordana, na istočnoj strani,"},{"v":42,"t":"kamo će se moći skloniti ubojica koji nehotice ubije svoga bližnjega a da prije nije imao mržnje prema njemu: da bi, bježeći u koji od ovih gradova, mogao spasiti svoj život."},{"v":43,"t":"To su: Bezer u pustinji, u zemlji Mišoru, za Rubenovce; Ramot u Gileadu za Gadovce, i Golan u Bašanu za Manašeovce."},{"v":44,"t":"Ovo je Zakon što ga je Mojsije postavio pred Izraelce;"},{"v":45,"t":"ovo su upute, zakoni i uredbe što ih je Mojsije dao Izraelcima kad su izišli iz Egipta,"},{"v":46,"t":"s one strane Jordana, u dolini nasuprot Bet Peoru, u zemlji amorejskoga kralja Sihona, koji je živio u Hešbonu i koga su potukli Mojsije i Izraelci pošto iziđoše iz Egipta."},{"v":47,"t":"Njegovu su zemlju zauzeli i zemlju bašanskoga kralja Oga, dvaju amorejskih kraljeva koji su živjeli preko Jordana na istoku,"},{"v":48,"t":"od Aroera, koji se nalazi na obali potoka Arnona, do brda Sirjona, to jest Hermona,"},{"v":49,"t":"i svu Arabu preko Jordana, s istoka do mora u Arabi, pod obroncima Pisge."}]},"5":{"hr":[{"v":1,"t":"Mojsije sazva sav Izrael te im reče: “Čuj, Izraele, naredbe i zapovijedi što ih danas izričem u tvoje uši! Naučite ih, držite i vršite."},{"v":2,"t":"Jahve, Bog naš, sklopio je s nama Savez na Horebu."},{"v":3,"t":"Nije Jahve sklopio taj Savez s našim očevima, nego baš s nama svima koji smo danas ovdje živi."},{"v":4,"t":"Licem je u lice Jahve govorio s vama na brdu isred ognja."},{"v":5,"t":"Ja sam u ono vrijeme stajao između Jahve i vas da vam objavim Jahvine riječi, jer se vi, u strahu od ognja, niste htjeli peti na brdo. Rekao je:"},{"v":6,"t":"'Ja sam Jahve, Bog tvoj, koji sam te izveo iz zemlje egipatske, iz kuće ropstva."},{"v":7,"t":"Nemoj imati drugih bogova uz mene!"},{"v":8,"t":"Ne pravi sebi lika ni obličja bilo čega što je gore na nebu, ili dolje na zemlji, ili u vodama pod zemljom."},{"v":9,"t":"Ne klanjaj im se niti im služi. Jer ja, Jahve, Bog tvoj, Bog sam ljubomoran. Kažnjavam grijeh otaca - onih koji me mrze - na djeci do trećeg i četvrtog koljena,"},{"v":10,"t":"a iskazujem milosrđe tisućama koji me ljube i vrše moje zapovijedi."},{"v":11,"t":"Ne uzimaj uzalud imena Jahve, Boga svoga, jer Jahve ne oprašta onome koji uzalud izgovara ime njegovo."},{"v":12,"t":"Dan subotnji obdržavaj i svetkuj, kako ti je naredio Jahve, Bog tvoj."},{"v":13,"t":"Šest dana radi i obavljaj sav svoj posao."},{"v":14,"t":"A sedmoga je dana subota, počinak posvećen Jahvi, Bogu tvome. Tada nikakva posla nemoj raditi: ni ti, ni sin tvoj, ni kći tvoja, ni sluga tvoj, ni sluškinja tvoja, ni vol tvoj, ni magarac tvoj, niti ikakvo živinče tvoje, niti došljak koji je unutar tvojih vrata; tako da mogne otpočinuti i sluga tvoj, i sluškinja tvoja kao i ti."},{"v":15,"t":"Sjeti se da si i ti bio rob u zemlji egipatskoj i da te odande izbavio Jahve, Bog tvoj, rukom jakom i ispruženom mišicom. Zato ti je zapovjedio Jahve, Bog tvoj, da držiš dan subotnji."},{"v":16,"t":"Poštuj oca svoga i majku svoju, kako ti je Jahve, Bog tvoj, zapovjedio, da dugo živiš i dobro ti bude na zemlji koju ti Jahve, Bog tvoj, daje."},{"v":17,"t":"Ne ubij!"},{"v":18,"t":"Ne učini preljuba!"},{"v":19,"t":"Ne ukradi!"},{"v":20,"t":"Ne svjedoči lažno na bližnjega svoga!"},{"v":21,"t":"Ne poželi žene bližnjega svoga! Ne poželi kuće bližnjega svoga, ni njive njegove, ni sluge njegova, ni sluškinje njegove, ni vola njegova, ni magarca njegova, niti išta što je bližnjega tvoga.'"},{"v":22,"t":"Te je riječi na brdu, isred ognja, oblaka i guste tmine, jakim glasom upravio Jahve svemu vašem zboru. Ništa nije dodavao nego ih je ispisao na dvije kamene ploče te ih predao meni."},{"v":23,"t":"A onda, kad čuste glas iz tmine, dok je brdo plamtjelo u ognju, k meni pristupiše svi vaši plemenski glavari i vaše starješine"},{"v":24,"t":"pa rekoše: 'Jahve, Bog naš, očitovao nam je, eto, svoju slavu i svoju veličajnost; čuli smo njegov glas isred ognja; danas smo vidjeli da čovjek može ostati na životu iako mu Bog govori."},{"v":25,"t":"A sad, zašto da umremo? Ovaj bi nas veliki oganj mogao proždrijeti; budemo li dalje slušali glas Jahve, Boga svoga, mogli bismo umrijeti."},{"v":26,"t":"Jer, koji je smrtnik ikad slušao glas Boga živoga kako govori isred ognja - kao mi - i ostao na životu?"},{"v":27,"t":"Ti se primakni i slušaj sve što će ti reći Jahve, Bog naš. A onda ti nama kaži sve što tebi Jahve, Bog naš, rekne, i mi ćemo to poslušati i izvršiti.'"},{"v":28,"t":"Jahve je čuo vaše riječi kad ste mi govorili pa mi reče: 'Čuo sam riječi što ih je taj narod tebi upravio. Sve što su rekli dobro je."},{"v":29,"t":"Kad bi samo njihova srca bila takva da me se uvijek boje i drže sve moje zapovijedi, da tako vazda budu sretni, oni i njihovo potomstvo!"},{"v":30,"t":"Hajde, reci im: Vratite se u svoje šatore!"},{"v":31,"t":"A ti ostani ovdje kod mene; kazat ću ti sve zapovijedi, zakone i uredbe kojima ćeš ih poučiti i koje će oni vršiti u zemlji što im je dajem u posjed.'"},{"v":32,"t":"Pazite, dakle, da radite kako vam je Jahve, Bog vaš, naložio! Ne skrećite ni desno ni lijevo."},{"v":33,"t":"Slijedite potpuno put koji vam je Jahve, Bog vaš, označio, da tako uzmognete živjeti, imati sreću i dug život u zemlji koju ćete zaposjesti."}]},"6":{"hr":[{"v":1,"t":"Ovo su zapovijedi, zakoni i uredbe koje mi Jahve, Bog vaš, zapovjedi da vas u njima poučim, kako biste ih vršili u zemlji u koju odlazite da je zaposjednete;"},{"v":2,"t":"da se svega svog vijeka bojiš Jahve, Boga svoga, ti, sin tvoj i sin tvoga sina, vršeći sve zakone njegove i sve zapovijedi njegove što ti ih danas propisujem, pa da imaš dug život."},{"v":3,"t":"Slušaj, Izraele, drži ih i vrši da ti dobro bude i da se razmnožiš u zemlji kojom teče med i mlijeko, kao što ti je obećao Jahve, Bog otaca tvojih."},{"v":4,"t":"Čuj, Izraele! Jahve je Bog naš, Jahve je jedan!"},{"v":5,"t":"Zato ljubi Jahvu, Boga svoga, svim srcem svojim, svom dušom svojom i svom snagom svojom!"},{"v":6,"t":"Riječi ove što ti ih danas naređujem neka ti se urežu u srce."},{"v":7,"t":"Napominji ih svojim sinovima. Govori im o njima kad sjediš u svojoj kući i kad ideš putem; kad liježeš i kad ustaješ."},{"v":8,"t":"Priveži ih na svoju ruku za znak i neka ti budu kao zapis među očima!"},{"v":9,"t":"Ispiši ih na dovratnicima kuće svoje i na vratima svojim!"},{"v":10,"t":"A kad te Jahve, Bog tvoj, dovede u zemlju za koju se zakleo tvojim ocima, Abrahamu, Izaku i Jakovu, da će je tebi dati - u velike i lijepe gradove kojih nisi zidao;"},{"v":11,"t":"u kuće pune svakog dobra kojih nisi punio; na iskopane čatrnje kojih nisi kopao; u vinograde i maslinike kojih nisi sadio - i sit se najedeš:"},{"v":12,"t":"pazi da ne zaboraviš Jahvu koji te izveo iz zemlje egipatske, iz kuće ropstva."},{"v":13,"t":"Boj se Jahve, Boga svoga; njemu iskazuj štovanje; njegovim imenom polaži prisegu."},{"v":14,"t":"Ne idite za drugim bogovima između bogova drugih naroda što su oko vas."},{"v":15,"t":"Jer je Jahve, Bog tvoj, što stoji u sredini tvojoj, ljubomoran Bog; gnjev bi Jahve, Boga tvoga, usplamtio protiv tebe i istrijebio te sa zemlje."},{"v":16,"t":"Ne iskušavajte Jahvu, Boga svoga, kao što ste ga iskušavali kod Mase."},{"v":17,"t":"Točno vršite zapovijedi Jahve, Boga svoga, upute njegove i zakone njegove koje je izdao."},{"v":18,"t":"Čini što je pravo i dobro u očima Jahve da ti dobro bude i da se domogneš dobre zemlje za koju se Jahve zakleo tvojim ocima"},{"v":19,"t":"da će iz nje protjerati sve tvoje neprijatelje ispred tebe; tako je obećao Jahve."},{"v":20,"t":"A kad te sutra zapita tvoj sin: što su te upute, zakoni i uredbe što ih je Jahve, Bog naš, vama propisao -"},{"v":21,"t":"kaži svome sinu: 'Bili smo faraonovi robovi u Egiptu, ali nas je Jahve izveo iz Egipta jakom rukom."},{"v":22,"t":"Na naše je oči Jahve učinio velike i strašne znakove i čudesa protiv Egipta, protiv faraona i protiv svega doma njegova,"},{"v":23,"t":"a nas je odande izveo da nas dovede i dade nam zemlju koju je zakletvom obećao ocima našim."},{"v":24,"t":"I naredio nam je Jahve da sve ove naredbe vršimo u strahopoštovanju prema Jahvi, Bogu svome, da bismo uvijek bili sretni i da živimo kao što je to danas.'"},{"v":25,"t":"Naša će, dakle, pravednost biti: držati i vršiti sve ove zapovijedi pred Jahvom, Bogom našim, kako nam je naredio."}]},"7":{"hr":[{"v":1,"t":"Kad te Jahve, Bog tvoj, uvede u zemlju u koju ideš da je zaposjedneš i kad ispred tebe otjera mnoge narode: Hetite, Girgašane, Amorejce, Kanaance, Perižane, Hivijce i Jebusejce - sedam naroda brojnijih i jačih od tebe -"},{"v":2,"t":"te kad ih Jahve, Bog tvoj, preda tebi i ti ih poraziš, udari ih prokletstvom; nemoj sklapati s njima saveza niti im iskazuj milosti."},{"v":3,"t":"Ne sklapaj ženidbe s njima, ne udavaj svoje kćeri za njihova sina niti ženi svoga sina njihovom kćeri;"},{"v":4,"t":"jer bi ona odvratila od mene sina tvoga; drugim bi bogovima on služio; Jahve bi se razgnjevio protiv vas i brzo bi te istrijebio."},{"v":5,"t":"Nego ovako učinite prema njima: porušite njihove žrtvenike, porazbijajte njihove stupove, njihove ašere počupajte a njihove kumire spalite."},{"v":6,"t":"TÓa ti si narod posvećen Jahvi, Bogu svome; tebe je Jahve, Bog tvoj, izabrao da među svim narodima koji su na zemlji budeš njegov predragi vlastiti narod."},{"v":7,"t":"Nije vas Jahve odabrao i prihvatio zato što biste vi bili brojniji od svih naroda - vi ste zapravo najmanji -"},{"v":8,"t":"nego zato što vas Jahve ljubi i drži zakletvu kojom se zakleo vašim ocima. Stoga vas je Jahve izveo jakom rukom i oslobodio vas iz kuće ropstva, ispod vlasti faraona, kralja egipatskoga."},{"v":9,"t":"Zato znaj da je Jahve, Bog tvoj, pravi Bog, Bog vjeran, koji drži svoj Savez i milost svoju iskazuje do tisuću koljena onima koji ga ljube i drže njegove zapovijedi."},{"v":10,"t":"A onima koji ga mrze uzvraća izravno njima samima; uništava bez odgađanja onoga koji ga mrzi: uzvraća izravno njemu samomu."},{"v":11,"t":"Stoga drži zapovijedi, zakone i uredbe koje ti danas nalažem da ih vršiš."},{"v":12,"t":"A za nagradu - budeš li slušao ove naloge, držao ih te izvršavao - Jahve, Bog tvoj, držat će ti Savez svoj i milost za koje se zakleo tvojim ocima."},{"v":13,"t":"Ljubit će te, blagoslivljati i razmnažati; blagoslivljat će plod utrobe tvoje i rod zemlje tvoje: žito tvoje, vino tvoje, ulje tvoje, mlad krava tvojih i prirast stoke tvoje u zemlji za koju se zakleo ocima tvojim da će je tebi dati."},{"v":14,"t":"Bit ćeš blagoslovljen nad sve narode; neće u tebe biti ni neplodna ni neplodne, ni među tvojom čeljadi ni među stokom tvojom."},{"v":15,"t":"Jahve će od tebe maknuti svaku bolest; neće na te pustiti ni jedno od strašnih zala egipatskih za koja znaš nego će njima pritiskati one koji te mrze."},{"v":16,"t":"Uništavaj sve narode koje ti Jahve, Bog tvoj, bude predavao. Neka ih ne sažaljuje oko tvoje. Nemoj se klanjati njihovim kumirima, jer bi ti to bilo zamkom."},{"v":17,"t":"Možda ćeš u svome srcu reći: 'Oni su narodi brojniji od mene, kako ću ih onda protjerati?'"},{"v":18,"t":"Ne boj ih se! Sjeti se što je Jahve, Bog tvoj, učinio faraonu i svemu Egiptu!"},{"v":19,"t":"Pomisli na velike kušnje što si ih vidio na svoje oči; na one znakove i čudesa pa na jaku ruku i ispruženu mišicu kojima te Jahve, Bog tvoj, izveo. Tako će Jahve, Bog tvoj, učiniti sa svim narodima kojih se plašiš."},{"v":20,"t":"Povrh toga, među njih će Jahve, Bog tvoj, slati stršljene dok ne izginu koji bi preostali i sakrili se pred tobom."},{"v":21,"t":"Ne strepi, dakle, pred njima! TÓa Jahve, Bog tvoj, u sredini je tvojoj, Bog silan i strahovit."},{"v":22,"t":"Malo će pomalo Jahve, Bog tvoj, ispred tebe uništiti one narode; i nećeš ih moći ujedanput sve istrijebiti da se zvijeri ne bi protiv tebe razmnožile."},{"v":23,"t":"Ali Jahve, Bog tvoj, tebi će ih predati i među njih unositi stravu dok ne budu uništeni."},{"v":24,"t":"I njihove će kraljeve predati u tvoje ruke da zatreš ime njihovo pod nebom. Nijedan se neće održati pred tobom dok ih ne uništiš."},{"v":25,"t":"Likove njihovih kumira spali! Ne hlepi za srebrom i zlatom što je na njima; ne uzimlji ga da ne budeš njime zaveden; jer bi to bilo gadno Jahvi, Bogu tvome."},{"v":26,"t":"Ne unosi gnusobe u svoju kuću da ne budeš udaren prokletstvom kao i ona; duboko je prezri i grozi se od nje jer je prokleta."}]},"8":{"hr":[{"v":1,"t":"Držite i vršite sve zapovijedi koje vam danas naređujem da biste živjeli i raznmožili se i da biste ušli i zaposjeli zemlju koju je Jahve pod zakletvom obećao ocima vašim."},{"v":2,"t":"Sjećaj se svega puta kojim te Jahve, Bog tvoj, vodio po pustinji ovih četrdeset godina da te ponizi, iskuša i dozna što ti je u srcu: hoćeš li držati zapovijedi njegove ili nećeš."},{"v":3,"t":"Ponižavao te i glađu morio, a onda te hranio manom - za koju nisi znao ni ti ni tvoji oci - da ti pokaže kako čovjek ne živi samo o kruhu nego da čovjek živi o svemu što izlazi iz usta Jahvinih."},{"v":4,"t":"Tvoja se odjeća na tebi nije izderala niti su ti noge oticale ovih četrdeset godina."},{"v":5,"t":"Priznaj onda u svome srcu da te Jahve, Bog tvoj, odgaja i popravlja, kao što čovjek odgaja sina svoga."},{"v":6,"t":"I drži zapovijedi Jahve, Boga svoga, hodeći putovima njegovim i bojeći se njega!"},{"v":7,"t":"TÓa Jahve, Bog tvoj, vodi te u dobru zemlju: zemlju potoka i vrela, dubinskih voda što izviru u dolinama i bregovima;"},{"v":8,"t":"zemlju pšenice i ječma, loze, smokava i šipaka, zemlju meda i maslina;"},{"v":9,"t":"zemlju u kojoj nećeš sirotinjski jesti kruha i gdje ti ništa neće nedostajati; zemlju gdje kamenje ima željeza i gdje ćeš iz njezinih brdina vaditi mjed."},{"v":10,"t":"Do sita ćeš jesti i blagoslivljati Jahvu, Boga svoga, zbog dobre zemlje koju ti je dao."},{"v":11,"t":"Čuvaj se da ne zaboraviš Jahvu, Boga svoga, zanemarujući njegove zapovijedi, njegove uredbe i njegove zakone koje ti danas dajem."},{"v":12,"t":"I pošto se najedeš do sitosti, posagradiš lijepe kuće i u njima se nastaniš;"},{"v":13,"t":"kad ti se krupna i sitna stoka namnoži; kad se nakupiš srebra i zlata i kada sve tvoje uznapreduje,"},{"v":14,"t":"nemoj da se uznese srce tvoje i da zaboraviš Jahvu, Boga svoga, koji te izveo iz zemlje egipatske, iz kuće ropstva;"},{"v":15,"t":"koji te proveo kroz onu veliku i strašnu pustinju, kroz zemlju plamenih zmija i štipavaca, suhim i bezvodnim krajem; koji ti je izveo vodu iz stijene tvrde kao kremen;"},{"v":16,"t":"koji te u pustinji hranio manom, nepoznatom tvojim ocima, da te ponizi i da te iskuša te da na kraju budeš sretan."},{"v":17,"t":"Ne reci tada u svome srcu: svojom sam moći i snagom svojih ruku sebi namakao ovo bogatstvo."},{"v":18,"t":"Sjeti se Jahve, Boga svoga! TÓa on ti je dao snagu da stječeš bogatstvo da tako ispuni - kao što je danas - svoj Savez za koji se zakleo tvojim ocima."},{"v":19,"t":"Ako li zaboraviš Jahvu, Boga svoga, i pođeš za drugim bogovima te njima budeš iskazivao štovanje, njima se klanjao, kunem vam se danas da ćete zacijelo izginuti;"},{"v":20,"t":"poput naroda koje će Jahve pogubiti pred vama, tako će i vas nestati jer niste poslušali glasa Jahve, Boga svoga."}]},"9":{"hr":[{"v":1,"t":"Slušaj, Izraele! Danas prelaziš preko Jordana da sebi podvrgneš narode i veće i brojnije nego što si ti; velike gradove, s utvrdama do nebesa;"},{"v":2,"t":"narod velik i gorostasan poput Anakovaca, koje već poznaješ i o kojima si slušao: 'Tko da odoli Anakovcima?'"},{"v":3,"t":"Znaj dakle danas da Jahve, Bog tvoj, ide pred tobom. On je vatra što proždire; on će ih oboriti, tebi ih podvrgnuti. A ti ćeš ih onda rastjerati i ubrzo pobiti, kako ti je Jahve i rekao."},{"v":4,"t":"Pošto ih otjera ispred tebe Jahve, Bog tvoj, nemoj reći u srcu svome: 'Jahve me uveo da zaposjednem ovu zemlju zbog moje pravednosti.' Naprotiv, zbog opačina onih naroda Jahve ih tjera ispred tebe."},{"v":5,"t":"Ne ideš ti da zaposjedneš njihovu zemlju zbog svoje pravednosti i čestitosti svoga srca, nego zato što Jahve, Bog tvoj, zbog opačine onih naroda tjera njih ispred tebe da tako održi riječ kojom se zakleo tvojim ocima: Abrahamu, Izaku i Jakovu."},{"v":6,"t":"Znaj, dakle, da ti Jahve, Bog tvoj, ne daje ovu dobru zemlju u posjed zbog tvoje pravednosti, jer si ti narod tvrde šije!"},{"v":7,"t":"Sjećaj se i ne zaboravljaj kako si u pustinji ljutio Jahvu, Boga svoga. Od dana kad ste izašli iz zemlje egipatske do dolaska na ovo mjesto, Jahvi ste se opirali."},{"v":8,"t":"Na Horebu ste rasrdili Jahvu i Jahve je na vas tako planuo da vas je htio uništiti."},{"v":9,"t":"Popeo sam se na brdo da primim kamene ploče, ploče Saveza što ga s vama sklopi Jahve. Na brdu sam ostao četrdeset dana i četrdeset noći: niti sam jeo kruha niti pio vode."},{"v":10,"t":"I dade mi Jahve dvije kamene ploče, ispisane prstom Božjim, na kojima bijahu sve riječi što vam ih je Jahve isred ognja na brdu rekao na dan zbora."},{"v":11,"t":"Kad je prošlo četrdeset dana i četrdeset noći, Jahve mi dade dvije kamene ploče - ploče Saveza."},{"v":12,"t":"I reče mi Jahve: 'Ustaj! Žurno siđi odavde, jer se pokvario narod tvoj koji si izveo iz Egipta. Brzo su zašli s puta koji sam im označio: već su sebi napravili livenog kumira.'"},{"v":13,"t":"Još mi reče Jahve: 'Promatrao sam taj narod. Zbilja je to narod tvrde šije!"},{"v":14,"t":"Pusti me da ih uništim i njihovo ime izbrišem pod nebesima, a od tebe da učinim narod i jači i brojniji nego što je ovaj!'"},{"v":15,"t":"Okrenuh se i siđoh niz brdo, a brdo svejednako plamtjelo u ognju. Dvije ploče Saveza bijahu mi u rukama."},{"v":16,"t":"Pogledah: zbilja ste sagriješili protiv Jahve, Boga svoga. Salili ste sebi tele od kovine. Tako ste brzo zašli s puta što vam ga Jahve bijaše označio."},{"v":17,"t":"Pograbih dvije ploče te ih bacih od sebe objema rukama - razbih ploče pred vašim očima."},{"v":18,"t":"Onda se ničice bacih pred Jahvu. Četrdeset dana i četrdeset noći - kao i prije - niti sam jeo kruha niti pio vode zbog svih grijeha koje ste počinili radeći zlo u očima Jahve i srdeći ga."},{"v":19,"t":"Jer se bojah srdžbe i gnjeva kojim je Jahve usplamtio na vas da vas zatre. Ali me i tada Jahve usliša."},{"v":20,"t":"I na Arona se Jahve silno rasrdio, htio ga uništiti. Tada se zauzeh i za Arona."},{"v":21,"t":"Vaš grijeh, tele što bijaste načinili, uzeh i sažegoh ga u vatri. U prah ga satrh i prah mu bacih u potok što teče s brda."},{"v":22,"t":"Kod Tabere, kod Mase i Kibrot Hataave srdili ste Jahvu."},{"v":23,"t":"Kad vas je Jahve slao od Kadeš Barnee govoreći: 'Idite gore i uzmite zemlju koju sam vam dao', pobunili ste se protiv riječi Jahve, Boga svoga; u nj se niste pouzdavali niti ste slušali njegov glas."},{"v":24,"t":"Nepokorni bijaste Jahvi otkad vas poznajem."},{"v":25,"t":"Zato sam pao ničice i ležao pred Jahvom četrdeset dana i četrdeset noći, jer Jahve bijaše rekao da će vas uništiti."},{"v":26,"t":"Jahvu sam molio i rekao: 'Gospodine moj, Jahve! Ne uništavaj naroda svoga, baštine svoje koju si izbavio u svojoj veličajnosti i svojom moćnom rukom izveo iz Egipta."},{"v":27,"t":"Sjeti se slugu svojih: Abrahama, Izaka i Jakova, a ne obaziri se na tvrdokornost ovoga naroda, na njegovu opačinu, na grijeh njegov,"},{"v":28,"t":"da se ne rekne u zemlji iz koje si nas izbavio: Jahve ih nije mogao uvesti u zemlju koju im je obećao, ili ih je mrzio pa ih je zato odveo da ih pomori u pustinji."},{"v":29,"t":"A oni su tvoj narod, tvoja baština, oni koje si izveo svojom velikom moći i ispruženom mišicom.'"}]},"10":{"hr":[{"v":1,"t":"U to vrijeme Jahve mi reče: 'Iskleši dvije kamene ploče kao i prijašnje pa se popni k meni na brdo; a napravi i drveni kovčeg."},{"v":2,"t":"Na ploče ću napisati riječi koje su bile na prvim pločama što si ih razbio. A onda ih položi u kovčeg.'"},{"v":3,"t":"Načinih kovčeg od bagremovine, isklesah dvije kamene ploče kao što bijahu prve, pa se, s dvjema pločama u ruci, popeh na brdo."},{"v":4,"t":"I napisa na te ploče, kao i prije, Deset riječi koje vam je Jahve rekao na brdu, isred ognja, na dan zbora. Onda ih Jahve dade meni."},{"v":5,"t":"Okrenuh se i siđoh s brda. Položih ploče u kovčeg koji bijah napravio. I stadoše ondje, kako mi je Jahve naredio."},{"v":6,"t":"Od Beerota sinova Jaakanovih odoše Izraelci u Moseru. Ondje umrije Aron i ondje bi pokopan. Svećenikom mjesto njega postade njegov sin Eleazar."},{"v":7,"t":"Odande odoše u Gudgodu; iz Gudgode u Jotbatu, u kraj bogat potocima."},{"v":8,"t":"U to vrijeme odvoji Jahve pleme Levijevo da nosi Kovčeg saveza Jahvina; da pred Jahvom stoji u njegovoj službi te da u njegovo ime blagoslivlja, kako radi i danas."},{"v":9,"t":"Stoga Levi nema udjela ni baštine sa svojom braćom: Jahve je njegova baština, kako mu je Jahve, Bog tvoj, i rekao."},{"v":10,"t":"Na brdu sam ostao, kao i prvi put, četrdeset dana i četrdeset noći. I usliša me Jahve i taj put; nije htio da te uništi,"},{"v":11,"t":"nego mi Jahve reče: 'Ustaj! Idi pred ovim narodom da uđu i zaposjednu zemlju za koju sam se zakleo njihovim ocima da ću im je dati.'"},{"v":12,"t":"Dakle, Izraele, što od tebe traži Jahve, Bog tvoj? Samo to da se bojiš Jahve, Boga svoga; da po svim putovima njegovim hodiš; da ga ljubiš i služiš Jahvi, Bogu svome, svim srcem svojim i svom dušom svojom;"},{"v":13,"t":"da držiš Jahvine zapovijedi i njegove zakone što ti ih danas za tvoje dobro dajem."},{"v":14,"t":"Evo, Jahvi, Bogu tvome, pripada nebo i nebo nad nebesima, zemlja i sve što je na njoj."},{"v":15,"t":"Ali Jahvi samo vaši oci omilješe i poslije njih izabrao je vas, potomke njihove, između svih naroda, kako je i danas."},{"v":16,"t":"Srce svoje obrežite; šiju više ne ukrućujte!"},{"v":17,"t":"Jer Jahve, Bog vaš, Bog je nad bogovima, Gospodar nad gospodarima, Bog velik, jak i strašan, koji nije pristran i ne da se podmititi;"},{"v":18,"t":"daje pravdu siroti i udovici; ljubi pridošlicu, daje mu hranu i odjeću."},{"v":19,"t":"Ljubite i vi pridošlicu, jer ste i sami bili pridošlice u zemlji egipatskoj."},{"v":20,"t":"Boj se Jahve, Boga svojeg; njemu služi; uza nj se priljubi; njegovim imenom priseži."},{"v":21,"t":"On je tvoja slava, Bog tvoj, koji je radi tebe učinio velika i čudesna djela što su ih vidjele tvoje oči."},{"v":22,"t":"Tvojih otaca, kad su se spustili u Egipat, bješe samo sedamdeset, a sad je Jahve, Bog tvoj, učinio te vas ima kao zvijezda na nebu."}]},"11":{"hr":[{"v":1,"t":"Ljubi, dakle, Jahvu, Boga svoga, i vrši u sve dane njegove naredbe, njegove zakone, uredbe i zapovijedi."},{"v":2,"t":"Vi, a ne vaši sinovi, koji nisu ni upoznali ni vidjeli pouke Jahve, Boga vašega, danas ste se osvjedočili o njegovoj veličajnosti, o njegovoj moćnoj ruci, ispruženoj mišici,"},{"v":3,"t":"o znamenjima njegovima i o djelima što ih učini usred Egipta na faraonu, kralju egipatskom, i na svoj zemlji njegovoj;"},{"v":4,"t":"što je učinio egipatskoj vojsci, njihovim konjima i kolima; kako ih je preplavio vodama Crvenog mora kad su vas progonili i kako ih je zatro do današnjeg dana;"},{"v":5,"t":"što je za vas radio u pustinji dok ne stigoste do ovoga mjesta;"},{"v":6,"t":"što je učinio s Datanom i Abiramom, sinovima Eliaba, Rubenova potomka, kad zemlja rastvori ralje svoje te ih proguta sred svega Izraela, njih i njihove obitelji, njihove šatore i sve što imahu."},{"v":7,"t":"Vaše su oči vidjele sva ta velika djela što ih je Jahve učinio."},{"v":8,"t":"Zato držite sve zapovijedi što vam ih danas naređujem da budete jaki te uzmete u posjed zemlju u koju idete da je osvojite;"},{"v":9,"t":"napokon, da dugo živite u zemlji za koju se zakleo Jahve ocima vašim da će je dati njima i njihovu potomstvu - zemlju kojom teče med i mlijeko."},{"v":10,"t":"Jer zemlja u koju ideš da je zaposjedneš nije kao zemlja egipatska iz koje ste izašli, gdje si, posijavši sjeme, morao svoj usjev svojom nogom natapati kao što se natapa povrtnjak."},{"v":11,"t":"Zemlja u koju idete da je zaposjednete zemlja je bregova i dolova i natapa je dažd nebeski;"},{"v":12,"t":"zemlja nad kojom Jahve, Bog tvoj, bdi; na kojoj oči Jahve, Boga tvoga, uvijek počivaju, od početka do svršetka godine."},{"v":13,"t":"Zato, ako doista poslušate zapovijedi koje vam danas izdajem i budete ljubili Jahvu, Boga svoga, i služili mu svim srcem svojim i svom dušom svojom,"},{"v":14,"t":"davat ću vašoj zemlji kišu u pravo vrijeme: u jesen i u proljeće, i moći ćeš sabirati svoje žito, svoje vino i svoje ulje;"},{"v":15,"t":"travu ću davati po tvome polju tvome blagu. Tako ćeš jesti i biti sit."},{"v":16,"t":"Pazite da se vaše srce ne zavede, da ne pođete stranputicom, da drugim bogovima ne iskazujete štovanje i da im se ne klanjate."},{"v":17,"t":"Jer tada bi na vas Jahve usplamtio gnjevom: nebesa bi zatvorio; kiše ne bi bilo; zemlja ne bi davala roda i vas bi brzo nestalo s te dobre zemlje koju vam Jahve daje."},{"v":18,"t":"Utisnite ove moje riječi u svoje srce i svoju dušu; kao znak ih privežite na svoju ruku; neka vam budu kao zapis među očima!"},{"v":19,"t":"Poučite u njima svoje sinove; izgovarajte ih kad sjedite u svojoj kući i kad idete putem; kad liježete i kad ustajete."},{"v":20,"t":"Ispišite ih na dovratnike svoje kuće i na svoja vrata"},{"v":21,"t":"da vaši dani i dani vaših sinova u zemlji za koju se Jahve zakleo vašim ocima da će im je dati - budu brojni kao dani nebesa nad zemljom."},{"v":22,"t":"Ako budete vjerno držali sve ove zapovijedi koje vam naređujem, vršili ih i ljubili Jahvu, Boga svoga, hodili svim njegovim putovima i čvrsto se priljubili uz njega,"},{"v":23,"t":"Jahve će ispred vas protjerati sve te narode i vi ćete s posjeda odagnati narode brojnije i jače od sebe."},{"v":24,"t":"Svako mjesto na koje stupi vaša noga bit će vaše; od pustinje i Libanona, od Rijeke, rijeke Eufrata, do Zapadnog mora sterat će se vaše područje."},{"v":25,"t":"Nitko se neće održati pred vama; strah i trepet raširit će Jahve, Bog vaš, po svoj zemlji u koju stupite, kako vam je rekao."},{"v":26,"t":"Gledajte! Nudim vam danas blagoslov i prokletstvo:"},{"v":27,"t":"blagoslov, budete li slušali zapovijedi Jahve, Boga svoga, koje vam danas dajem;"},{"v":28,"t":"a prokletstvo, ne budete li slušali zapovijedi Jahve, Boga svoga, nego sađete s puta koji vam danas određujem te pođete za drugim bogovima kojih niste poznavali."},{"v":29,"t":"Kada te Jahve, Bog tvoj, uvede u zemlju u koju ideš da je zaposjedneš, tada nad gorom Gerizimom izreci blagoslov, a prokletstvo nad gorom Ebalom."},{"v":30,"t":"Te se gore izdižu, kako znate, s onu stranu Jordana, za putom prema zapadu, u zemlji Kanaanaca, koji žive u Arabi, nasuprot Gilgalu, uz Hrast More."},{"v":31,"t":"Eto ćete prijeći preko Jordana da zaposjednete zemlju koju vam daje Jahve, Bog vaš. Zaposjednite je i nastanite se u njoj."},{"v":32,"t":"Ali držite i vršite sve zakone i uredbe koje vam danas izlažem."}]},"12":{"hr":[{"v":1,"t":"Ovo su zakoni i uredbe što vam ih valja držati i vršiti u zemlji koju vam Jahve, Bog otaca vaših, daje u posjed za sve dane što budete živjeli na zemlji."},{"v":2,"t":"Sravnite sa zemljom sva mjesta na kojima su narodi koje ćete protjerati iskazivali štovanje svojim bogovima, nalazila se ona na visokim brdima, na humovima ili pod kakvim zelenim drvetom."},{"v":3,"t":"Porušite njihove žrtvenike, porazbijajte njihove stupove, spalite im ašere; smrvite kipove njihovih bogova, zatrite im imena s onih mjesta."},{"v":4,"t":"Jahvi, Bogu svome, nemojte onako iskazivati štovanje."},{"v":5,"t":"Jahvu, Boga svoga, tražite jedino na mjestu koje je on odabrao, sred svih vaših plemena, da ondje stavi svoje ime i da ondje prebiva;"},{"v":6,"t":"onamo donosite svoje paljenice i svoje klanice, svoje desetine i darove svojih ruku, svoje zavjetne i dragovoljne prinose i prvine od svoga krupnoga i sitnoga blaga."},{"v":7,"t":"Blagujte ondje, vi i vaše obitelji, u nazočnosti Jahve, Boga svoga; veselite se svime što su vaše ruke namaknule i što vam je Jahve, Bog vaš, blagoslovom udijelio."},{"v":8,"t":"Nemojte raditi čak ni kako radimo ovdje danas - svatko što se njemu čini dobro -"},{"v":9,"t":"jer još niste stigli u Počivalište, u baštinu koju ti daje Jahve, Bog tvoj."},{"v":10,"t":"Ali kad prijeđete preko Jordana i nastanite se u zemlji koju vam Jahve, Bog vaš, daje u baštinu, kad vas smiri od svih neprijatelja koji budu oko vas te budete živjeli bez straha,"},{"v":11,"t":"onda ćete donositi sve što vam naređujem: svoje paljenice, svoje klanice, svoje desetine, darove svojih ruku i sve svoje izabrane zavjetnice koje budete zavjetovali Jahvi - na mjesto koje Jahve, Bog vaš, odabere da ondje nastani svoje ime."},{"v":12,"t":"Veselite se tada pred Jahvom, Bogom svojim, vi, vaši sinovi i kćeri, vaše sluge i sluškinje i levit koji bude u vašim gradovima, jer on nema s vama udjela ni baštine."},{"v":13,"t":"Pazi da ne prinosiš svojih žrtava paljenica na bilo kojem mjestu što ga zamijetiš,"},{"v":14,"t":"nego samo na mjestu što ga odabere Jahve, u jednome od tvojih plemena. Tu prinosi svoje paljenice i tu obavljaj sve što ti naređujem."},{"v":15,"t":"Ali svaki put kad ti srce zaželi, možeš zaklati i jesti mesa u svim svojim gradovima, prema blagoslovu koji ti Jahve, Bog tvoj, bude davao. I nečist i čist može ga jesti, kao da je od srne ili jelena."},{"v":16,"t":"Ali krvi nemojte blagovati; istočite je na zemlju kao vodu."},{"v":17,"t":"Po svojim gradovima nemojte jesti desetine svoga žita, svoga vina, svoga ulja ni prvine svoga krupnog ili sitnog blaga; niti išta od svojih zavjetovanih i od svojih dragovoljnih prinosa, ni od prinosa svojih ruku,"},{"v":18,"t":"nego ćeš to blagovati pred Jahvom, Bogom svojim, u mjestu koje Jahve, Bog tvoj, odabere, ti, tvoj sin, tvoja kći, tvoj sluga, tvoja sluškinja i levit koji bude u tvojim gradovima. Proveseli se u nazočnosti Jahve, Boga svoga, svime što ti ruka namakne."},{"v":19,"t":"Pazi da nikad ne zaboraviš levita dok si na svojoj zemlji."},{"v":20,"t":"Kad ti Jahve, Bog tvoj, proširi tvoje područje, kao što ti je rekao, i ti rekneš: 'Ja bih jeo mesa' - jer želiš jesti mesa - možeš ga jesti koliko ti duša želi."},{"v":21,"t":"Bude li mjesto koje Jahve, Bog tvoj, odabere da u njemu svoje ime smjesti daleko od tebe, onda možeš zaklati bilo što od svoje krupne ili sitne stoke što ti je Jahve dadne - kako sam ti već naredio - te jesti u bilo kojem svome gradu koliko ti duša želi."},{"v":22,"t":"Jedi ga ipak onako kako se jede srna ili jelen: neka ga jedu zajedno čisti i nečisti."},{"v":23,"t":"Samo, pazi da ne jedeš krvi! Ta krv je život. Ne smiješ jesti život s mesom."},{"v":24,"t":"Ne blaguj je; istoči je na zemlju kao vodu."},{"v":25,"t":"Ne smiješ je jesti, da bude dobro i tebi i tvojim sinovima poslije tebe kad činiš što je pravo u očima Jahvinim."},{"v":26,"t":"Ali svoje posvećene prinose i svoje zavjetne prinose uzmi i nosi na mjesto koje Jahve odabere."},{"v":27,"t":"Tu prinesi svoje paljenice, meso i krv, na žrtveniku Jahve, Boga svoga. Ali krv od svojih klanica istoči na žrtvenik Jahve, Boga svoga, a meso pojedi."},{"v":28,"t":"Drži i vrši sve ove naredbe što ti ih propisujem, da bude dobro zauvijek tebi i tvojim sinovima poslije tebe kad činiš što je dobro i pravedno u očima Jahve, Boga svoga."},{"v":29,"t":"A kad Jahve, Bog tvoj, istrijebi narode na koje ideš da ih otjeraš s posjeda ispred sebe i kad ih otjeraš te se u njihovoj zemlji nastaniš,"},{"v":30,"t":"čuvaj se da ne padneš u zamku; ne pođi za njima pošto budu uništeni ispred tebe. Ne istražuj o njihovim bogovima i ne govori: 'Kako su oni narodi štovali svoje bogove, tako ću i ja.'"},{"v":31,"t":"Nemoj onako postupati prema Jahvi, Bogu svome. TÓa Jahvi je zazorno i mrsko sve što su oni činili svojim bogovima. Čak su svoje sinove i kćeri spaljivali u čast svojim bogovima."}]},"13":{"hr":[{"v":1,"t":"Sve što vam naređujem držite; tomu ništa ne domeći i ništa ne oduzimaj."},{"v":2,"t":"Ako se u tvojoj sredini pojavi kakav prorok ili čovjek sa snoviđenjima pa ti iznese kakvo znamenje ili čudo;"},{"v":3,"t":"i to se znamenje ili čudo o kojem ti je govorio ispuni i onda ti on rekne: 'Pođimo sad za drugim bogovima kojih dosad ne poznaješ i njima iskazujmo štovanje',"},{"v":4,"t":"nemoj slušati riječi toga proroka ni sne toga sanjača: tÓa to vas iskušava Jahve, Bog vaš; hoće da dozna ljubite li zbilja Jahvu, Boga svoga, svim srcem svojim i svom dušom svojom."},{"v":5,"t":"Idite samo za Jahvom, Bogom svojim; njega se bojte; njegove zapovijedi vršite; njegov glas slušajte; njemu štovanje iskazujte; uz njega se priljubite."},{"v":6,"t":"A onaj prorok ili sanjač neka se pogubi jer je poticao na otpad od Jahve, Boga vašega, koji vas je izveo iz zemlje egipatske i otkupio vas iz kuće ropstva. Onaj te htio zavesti s puta kojim ti je Jahve, Bog tvoj, naredio da ideš. Tako treba da iskorijeniš zlo iz svoje sredine."},{"v":7,"t":"Kad bi te brat tvoj, sin majke tvoje, ili sin tvoj vlastiti, kći tvoja, žena u tvom naručju ili prijatelj tvoj koji ti je kao i život, potajno zavodio govoreći: 'Hajde da iskazujemo štovanje drugim bogovima', kojih ne poznaješ ni ti niti su ih poznavali tvoji oci,"},{"v":8,"t":"bogovima onih naroda što oko vas budu, bilo tebi blizu bilo od tebe daleko, od jednoga kraja zemlje do drugoga -"},{"v":9,"t":"nemoj pristati niti ga slušaj! Neka ga tvoje oko ne sažaljuje; ne štedi ga i ne sakrivaj ga"},{"v":10,"t":"nego ga ubij! Neka se najprije tvoja ruka digne na nj da ga usmrtiš, a onda ruka svega naroda."},{"v":11,"t":"Zaspi ga kamenjem dok ne umre, jer je kušao da te odvrati od Jahve, Boga tvoga, koji te izvede iz zemlje egipatske, iz kuće ropstva."},{"v":12,"t":"Sav će se Izrael, kad to čuje, napuniti strahom te više neće počinjati takva zla u tvojoj sredini."},{"v":13,"t":"Ako u kojem tvome gradu što ti ga Jahve, Bog tvoj, dadne da se u njemu nastaniš, čuješ gdje govore:"},{"v":14,"t":"'Pojavile se ništarije iz tvoje sredine i zavedoše žitelje svoga grada kazujući: Hajde da služimo drugim bogovima! - kojih vi inače ne poznajete -"},{"v":15,"t":"tada dobro istraži, raspitaj se i temeljito izvidi. Bude li istina i doista se ta grozota učinila u tvojoj sredini,"},{"v":16,"t":"onda posijeci oštrim mačem stanovništvo toga grada, izvrši nad njim kleto uništenje i nad svime što bude u njemu."},{"v":17,"t":"Snesi onda sav plijen nasred trga te spali grad sa svim plijenom kao paljenicu Jahvi, Bogu svome. Neka zauvijek ostane ruševina i neka se više nikada ne sazida."},{"v":18,"t":"Od onoga što je bilo prokletstvom udareno neka ništa ne prione za tvoju ruku, da Jahve odustane od žestine svoga gnjeva; da ti iskaže milosrđe, smiluje ti se i razmnoži te, kako se zakleo tvojim ocima"},{"v":19,"t":"ako ti budeš slušao glas Jahve, Boga svoga, držeći sve njegove zapovijedi koje ti danas naređujem i vršeći što je pravo u očima Jahve, Boga tvoga."}]},"14":{"hr":[{"v":1,"t":"Vi ste sinovi Jahve, Boga svoga. Nemojte na sebi praviti ureza ni podstriga na čelu za pokojnikom."},{"v":2,"t":"TÓa ti si narod posvećen Jahvi, Bogu svome; Jahve je odabrao tebe između svih naroda na zemlji da budeš njegov narod, njegova predraga svojina."},{"v":3,"t":"Ništa odvratno nemojte jesti."},{"v":4,"t":"Ovo su životinje koje možete jesti: vol, ovca, koza,"},{"v":5,"t":"jelen, srna, srndać, kozorog, antilopa, bivol i divokoza;"},{"v":6,"t":"možete jesti svaku životinju koja ima razdvojene papke - nadvoje posve razdvojene - i koja preživa."},{"v":7,"t":"Samo od preživača ili od životinja s razdvojenim čaporcima ne možete jesti ove : devu, arnebeta i svisca. Te, naime, iako preživaju, nemaju razdvojenih papaka; neka su za vas nečiste."},{"v":8,"t":"A svinja, premda ima papke razdvojene, ne preživa: neka je za vas nečista. Njezina mesa nemojte jesti niti se njezina strva doticati."},{"v":9,"t":"A od svega što u vodi živi ovo možete jesti: što god ima ljuske i peraje, možete jesti."},{"v":10,"t":"A što nema ljusaka i peraja, ne smijete jesti. To neka je za vas nečisto."},{"v":11,"t":"Svaku čistu pticu možete jesti."},{"v":12,"t":"Ali ovih ne smijete jesti: orla strvinara i jastreba,"},{"v":13,"t":"tetrijeba, sokola bilo koje vrste;"},{"v":14,"t":"gavrana bilo koje vrste;"},{"v":15,"t":"noja, kopca, galeba ni kraguja bilo koje vrste;"},{"v":16,"t":"sove, jejine i labuda;"},{"v":17,"t":"pelikana, bijelog strvinara i gnjurca;"},{"v":18,"t":"rode, čaplje bilo koje vrste; pupavca i šišmiša."},{"v":19,"t":"Svi krilati kukci neka su za vas nečisti - ne smijete ih jesti."},{"v":20,"t":"Sve krilato čisto možete jesti."},{"v":21,"t":"Ne smijete jesti ništa što crkne. Daj to pridošlici koji boravi u tvojim gradovima neka jede ili pak prodaj tuđincu. Jer ti si narod posvećen Jahvi, Bogu svome. Ne kuhaj kozleta u mlijeku njegove majke!"},{"v":22,"t":"Odvajaj desetinu dohotka svake godine od svega što tvoj usjev u polju donese."},{"v":23,"t":"A onda blaguj desetine svoga žita, svoga vina, svoga ulja i prvine svoje krupne i sitne stoke u nazočnosti Jahve, Boga svoga, na mjestu koje on odabere da svoje ime ondje nastani; da se tako naučiš zauvijek bojati se Jahve, Boga svoga."},{"v":24,"t":"Bude li ti put predug te ne mogneš donijeti desetine - jer je mjesto što ga Jahve odabere da u njemu nastani svoje ime previše daleko od tebe - tada, kad te Jahve, Bog tvoj, blagoslovi,"},{"v":25,"t":"prodaj to za novac, uzmi novac u ruku pa idi u mjesto što ga odabere Jahve, Bog tvoj."},{"v":26,"t":"Ondje za novac kupi što želiš: goveče, sitno živinče, vino ili opojno piće - što god ti duša zaželi. Ondje u nazočnosti Jahve, Boga svoga, blaguj i veseli se ti i tvoji ukućani."},{"v":27,"t":"Ne zanemaruj levita koji bude u tvojim gradovima, jer on nema udjela ni baštine s tobom."},{"v":28,"t":"Na kraju svake treće godine iznesi svu desetinu svoga prihoda od te godine i položi je na svoja vrata."},{"v":29,"t":"Pa neka dođe levit - jer nema udjela ni baštine s tobom - došljak, sirota i udovica koji budu živjeli u tvom gradu i neka jedu i neka se nasite. Tako će te blagoslivljati Jahve, Bog tvoj, u svim poslovima što ih tvoja ruka poduzme."}]},"15":{"hr":[{"v":1,"t":"Na završetku sedme godine opraštaj dugove."},{"v":2,"t":"Ovako neka bude opraštanje: neka svatko oprosti dužniku svoje potraživanje; neka ne utjeruje duga od svoga bližnjega ni od svoga brata kad se jednom proglasi Jahvino otpuštanje dugova."},{"v":3,"t":"Možeš tražiti od tuđina, ali ono što se tvoga nađe kod tvoga brata treba da otpustiš,"},{"v":4,"t":"da ne bude siromaha kod tebe. TÓa Jahve će te obilno blagoslivljati u zemlji koju ti Jahve, Bog tvoj, daje u baštinu da je zaposjedneš,"},{"v":5,"t":"samo ako budeš dobro slušao glas Jahve, Boga svoga, držeći i vršeći sve ove zapovijedi što ti ih danas naređujem."},{"v":6,"t":"Jahve, Bog tvoj, blagoslivljat će te kako ti je obećao te ćeš moći zajmove davati mnogim narodima, a sam ih nećeš morati uzimati; i nad mnogim ćeš narodima vladati, dok oni nad tobom neće gospodariti."},{"v":7,"t":"Nađe li se kod tebe kakav siromah, netko od tvoje braće u kojem god gradu u zemlji što ti je Jahve, Bog tvoj, dadne, ne budi tvrda srca niti zatvaraj svoje ruke prema svome siromašnome bratu,"},{"v":8,"t":"nego mu širom rastvori svoju ruku i spremno mu daj što mu nedostaje."},{"v":9,"t":"Čuvaj se da ti se u srcu ne porodi opaka misao te rekneš: 'Sedma se godina, godina otpuštanja dugova, već približuje' - i da prijekim okom pogledaš svoga siromašnog brata i ništa mu ne dadneš. On bi zazvao Jahvu protiv tebe i grijeh bi bio na tebi."},{"v":10,"t":"Daj mu rado, a ne da ti srce bude zlovoljno kad mu daješ, jer će te zbog toga blagoslivljati Jahve, Bog tvoj, u svakom poslu tvome i u svakom pothvatu ruku tvojih."},{"v":11,"t":"Kako siromaha nikad neće nestati iz zemlje, zapovijedam ti: širom otvaraj svoju ruku svome bratu, svome siromahu i potrebitu u zemlji svojoj."},{"v":12,"t":"Ako se tebi proda brat tvoj - Hebrejac ili Hebrejka - neka ti služi šest godina, a sedme ga godine otpusti od sebe slobodna."},{"v":13,"t":"Kad ga slobodna od sebe otpustiš, ne šalji ga praznih ruku."},{"v":14,"t":"Daruj ga čime između stoke svoje, s gumna svoga i iz badnja svoga; čime te već Jahve, Bog tvoj, blagoslovio, od toga i njemu daj."},{"v":15,"t":"Sjećaj se kako si bio rob u zemlji egipatskoj i kako te Jahve, Bog tvoj, otkupio. Zato ti ovo zapovijedam danas."},{"v":16,"t":"Ali ako ti on kaže: 'Neću da odlazim od tebe', jer voli tebe i dom tvoj i jer mu je kod tebe bilo dobro -"},{"v":17,"t":"uzmi tada šilo i probuši mu uho na vratima, i neka ti bude robom zauvijek! Tako isto učini i sa svojom sluškinjom."},{"v":18,"t":"Kad ga budeš otpuštao od sebe slobodna, neka ti ne bude teško, jer je zavrijedio dvostruku najamničku plaću za šest godina što ti je služio. Zato će te Jahve, Bog tvoj, blagosloviti u svemu što budeš radio."},{"v":19,"t":"Sve muške prvine što ih omladi tvoja krupna i sitna stoka posveti Jahvi, Bogu svome! Stoga vola prvenca nemoj uprezati niti strići prvenca od svoje sitne stoke."},{"v":20,"t":"Blaguj ga ti i tvoj dom svake godine u nazočnosti Jahve, Boga svoga, u mjestu što ga odabere Jahve."},{"v":21,"t":"Ali ako bi imali kakvu manu, ako bi bili hromi ili slijepi ili imali kakvu god ružnu manu, nemoj ih žrtvovati Jahvi, Bogu svomu!"},{"v":22,"t":"Pojedi ih u svojoj kući. I nečist i čist mogu ih jesti, kao srnu i jelena."},{"v":23,"t":"Jedino krvi njihove ne smiješ jesti! Istoči je na zemlju kao vodu."}]},"16":{"hr":[{"v":1,"t":"Drži mjesec Abib i slavi Pashu u čast Jahvi, Bogu svome, jer te Jahve, Bog tvoj, u mjesecu Abibu izveo noću iz Egipta."},{"v":2,"t":"Kao pashu u čast Jahvi, Bogu svome, žrtvuj ovce i goveda u mjestu koje Jahve odabere da u njemu nastani ime svoje."},{"v":3,"t":"Ništa ukvasano nemoj s njome jesti; nego sedam dana jedi beskvasan kruh - kruh nevoljnički - budući da si u žurbi izišao iz zemlje egipatske: da se svega svog vijeka sjećaš dana kad si izišao iz zemlje egipatske."},{"v":4,"t":"Neka se sedam dana u tebe ne vidi kvasac na svemu tvome području i ništa od mesa žrtve što je zakolješ navečer prvoga dana ne smije ostati preko noći do jutra."},{"v":5,"t":"Nije ti dopušteno žrtvovati pashu u bilo kojem gradu što ti ga dadne Jahve, Bog tvoj,"},{"v":6,"t":"nego u mjestu koje odabere Jahve, Bog tvoj, da ondje nastani ime svoje; samo tu žrtvuj pashu u predvečerje, o zalasku sunca, jer u to si vrijeme izišao iz Egipta."},{"v":7,"t":"Skuhaj je i pojedi na mjestu koje odabere Jahve, Bog tvoj. Ujutro se onda okreni i zaputi svojim šatorima."},{"v":8,"t":"Šest dana jedi beskvasan kruh, a sedmoga dana neka bude svečani zbor u čast Jahvi, Bogu tvome. Posla nikakva ne radi!"},{"v":9,"t":"Nabroj sedam tjedana; a tih sedam tjedana uzmi brojiti kad srp počne žeti klasje."},{"v":10,"t":"Tada drži Blagdan sedmica u čast Jahvi, Bogu svome, prinoseći dragovoljni prinos iz svoje ruke, kako te već Jahve, Bog tvoj, bude blagoslovio."},{"v":11,"t":"I proveseli se tada u nazočnosti Jahve, Boga svoga - na mjestu što ga Jahve, Bog tvoj, odabere da ondje nastani ime svoje - ti, sin tvoj i kći tvoja, sluga tvoj i sluškinja tvoja, levit koji bude u tvome gradu, došljak, sirota i udovica što budu kod tebe."},{"v":12,"t":"Sjećaj se da si i sam bio rob u Egiptu. Zato drži i vrši ove uredbe."},{"v":13,"t":"Blagdan sjenica slavi sedam dana pošto pokupiš plodove sa svoga gumna i iz svoga badnja."},{"v":14,"t":"Proveseli se na svoj blagdan ti, sin tvoj, kći tvoja, sluga tvoj, sluškinja tvoja, levit i došljak, sirota i udovica što se nađe u tvome gradu."},{"v":15,"t":"Svetkuj u čast Jahvi, Bogu svome, sedam dana na mjestu koje odabere Jahve, jer će te Jahve, Bog tvoj, blagoslovom obasipati u svim tvojim žetvama, u svakom poslu ruku tvojih, da budeš potpuno veseo."},{"v":16,"t":"Triput u godini neka se pokažu svi tvoji muškarci pred Jahvom, Bogom tvojim, na mjestu koje on odabere: na Blagdan beskvasnog kruha, na Blagdan sedmica i na Blagdan sjenica. Ali neka nitko ne dođe pred Jahvu praznih ruku,"},{"v":17,"t":"nego neka svatko prinese što može, prema blagoslovu koji ti je udijelio Jahve, Bog tvoj."},{"v":18,"t":"U svakom gradu koji ti dade Jahve, Bog tvoj, postavi suce i nadglednike za svoja plemena da narodom pravedno upravljaju."},{"v":19,"t":"Ne iskrivljuj pravde; ne budi pristran; ne primaj mita, jer mito zasljepljuje oči mudrih, a ugrožava stvar pravednih."},{"v":20,"t":"Teži za samom pravdom, da dugo živiš i zaposjedneš zemlju koju ti Jahve, Bog tvoj, daje."},{"v":21,"t":"Ne postavljaj ašere ni od kakva drveta oko žrtvenika Jahve, Boga svoga, koji podigneš;"},{"v":22,"t":"i ne podiži stupova, jer su na zazor Jahvi, Bogu tvome."}]},"17":{"hr":[{"v":1,"t":"Ne žrtvuj Jahvi, Bogu svome, ni vola ni ovna koji bi na sebi imao manu ili kakvo zlo, jer bi to bilo ružno pred Jahvom, Bogom tvojim."},{"v":2,"t":"Ako se u tvojoj sredini - u bilo kojem tvojem gradu što ti ga dade Jahve, Bog tvoj - nađe čovjek ili žena da učini što je zlo u očima Jahve, Boga tvoga, i krši njegov Savez:"},{"v":3,"t":"otišavši da iskazuje štovanje drugim bogovima te se pokloni njima, suncu, mjesecu ili bilo čemu od nebeske vojske, a što sam ja zabranio,"},{"v":4,"t":"i tebi se to javi i ti to čuješ, onda pomno istraži; i bude li istina i doista se ta grozota učinila u Izraelu,"},{"v":5,"t":"onda toga čovjeka ili tu ženu koji učiniše takvu opačinu izvedi na gradska vrata te ih kamenuj da poginu."},{"v":6,"t":"Na smrt osuđeni neka se pogubi na iskaz dvojice ili trojice svjedoka. Na riječ jednoga svjedoka ne smije se pogubiti."},{"v":7,"t":"Neka najprije svjedoci dignu ruku na nj da ga smaknu, a poslije toga neka je digne sav narod. Tako ćeš iskorijeniti zlo iz svoje sredine."},{"v":8,"t":"Bude li ti preteško štogod rasuditi: ubojstvo, sukob o pravima, kakvu ozljedu ili svađu u tvome gradu, tada ustani i pođi u mjesto što ga odabere Jahve, Bog tvoj."},{"v":9,"t":"Obrati se svećenicima, levitima i sucu koji bude za ono vrijeme. Njih pitaj, oni će ti rasuditi."},{"v":10,"t":"I učini onako kako ti budu kazali u mjestu koje Jahve odabere. Pazi: sve učini kako te upute."},{"v":11,"t":"Uradi prema uputi koju ti dadnu i prema presudi koju donesu. Od presude koju ti kažu ne odstupaj ni desno ni lijevo."},{"v":12,"t":"Ako bi se tko drsko odupro i ne bi poslušao ni svećenika koji ondje stoji da služi Jahvi, Bogu tvome, ni suca, neka se taj čovjek pogubi. Tako ćeš iskorijeniti zlo iz Izraela,"},{"v":13,"t":"a sav će se narod, kad sazna, bojati i više se neće drsko odupirati."},{"v":14,"t":"Kad stigneš u zemlju koju ti Jahve, Bog tvoj, daje; kad je zaposjedneš i u njoj se nastaniš, pa onda kažeš: 'Želim da nad sobom postavim kralja, kako ga imaju svi drugi narodi oko mene' -"},{"v":15,"t":"tada ćeš onoga koga Jahve, Bog tvoj, odabere, sebi postaviti za kralja. Nekoga od svoje braće postavi sebi za kralja, a ne smiješ postavljati nad sobom tuđina koji ti nije brat."},{"v":16,"t":"Samo neka ne drži mnogo konja i ne šalje naroda u Egipat da poveća broj konja. Jer vam je Jahve rekao: 'Ovim se putem nikada više ne vraćajte!'"},{"v":17,"t":"I neka nema mnogo žena da mu srce ne pođe stranputicom; i neka sebi ne gomila srebra ni zlata!"},{"v":18,"t":"A kad sjedne na kraljevsko prijestolje, neka sebi na svitak prepiše ovaj Zakon od svećenika Levijevaca."},{"v":19,"t":"Neka ga drži uza se; neka ga čita sve vrijeme svoga života da nauči bojati se Jahve, Boga svoga, držati sve riječi ovoga Zakona i vršiti ove odredbe;"},{"v":20,"t":"da se svojim srcem ne uzdigne iznad svoje braće i da ne skrene od ove zapovijedi ni desno ni lijevo, kako bi dugo kraljevao, on i sinovi njegovi, u Izraelu."}]},"18":{"hr":[{"v":1,"t":"Svećenici Levijevci - sve pleme Levijevo - neka nemaju udjela ni baštine s Izraelom; neka žive od žrtava paljenih Jahvi i od njegove baštine."},{"v":2,"t":"Neka, dakle, nemaju baštine među svojom braćom: Jahve je njihova baština, kako im je i rekao."},{"v":3,"t":"Ovo neka bude svećenička pristojba od naroda - od onih koji žrtve prinose, bilo to goveče ili što od sitne stoke: svećeniku treba dati pleće, vilice i želudac."},{"v":4,"t":"Davaj mu i prvine od svoga žita, od svoga vina, od svoga ulja i prvine od vune svojih ovaca,"},{"v":5,"t":"jer je njega odabrao Jahve, Bog tvoj, od svih tvojih plemena; njega i njegove sinove, da zauvijek stoje pred Jahvom, Bogom tvojim, te da obavljaju službu i blagoslivljaju u ime Jahve."},{"v":6,"t":"Ako bi koji levit što boravi u nekom tvome gradu, bilo gdje u Izraelu, svom dušom zaželio da dođe u mjesto što ga Jahve odabere,"},{"v":7,"t":"može tu službovati u ime Jahve, Boga svoga, kao i druga njegova braća Levijevci koji stoje ondje pred Jahvom."},{"v":8,"t":"Neka jede jednak dio kao i drugi, bez obzira na prodanu očevinu."},{"v":9,"t":"Kad uđeš u zemlju koju ti daje Jahve, Bog tvoj, nemoj se priučavati na odvratne čine onih naroda."},{"v":10,"t":"Neka se kod tebe ne nađe nitko tko bi kroz oganj gonio svoga sina ili svoju kćer; tko bi se bavio gatanjem, čaranjem, vračanjem i čarobnjaštvom;"},{"v":11,"t":"nitko tko bi bajao, zazivao duhove i duše predaka ili se obraćao na pokojnike."},{"v":12,"t":"Jer tko god takvo što čini gadi se Jahvi; zbog takvih odvratnosti njih i goni ispred tebe Jahve, Bog tvoj."},{"v":13,"t":"Budi posve vjeran Jahvi, Bogu svome."},{"v":14,"t":"Narodi koje ćeš naskoro otjerati s posjeda slušaju vračare i gatare, ali tebi to Jahve, Bog tvoj, ne dopušta."},{"v":15,"t":"Proroka kao što sam ja, iz tvoje sredine, od tvoje braće, podignut će ti Jahve, Bog tvoj: njega slušajte!"},{"v":16,"t":"Posve onako kako si i tražio od Jahve, Boga svoga, na Horebu, na dan zbora, kada si govorio: 'Neću više da slušam glas Jahve, Boga svoga, niti želim više gledati taj silni oganj da ne poginem!'"},{"v":17,"t":"Nato mi reče Jahve: 'Pravo su rekli."},{"v":18,"t":"Podignut ću im proroka između njihove braće, kao što si ti. Stavit ću svoje riječi u njegova usta da im kaže sve što mu zapovjedim."},{"v":19,"t":"A ne bude li tko poslušao mojih riječi što ih prorok bude govorio u moje ime, taj će odgovarati preda mnom."},{"v":20,"t":"A prorok koji bi se usuđivao govoriti što u moje ime što ja ne budem zapovjedio da govori i koji bi govorio u ime drugih bogova, takav prorok neka se pogubi.'"},{"v":21,"t":"Možda ćeš reći u svome srcu: 'Kako ćemo raspoznati riječ koju Jahve nije izrekao?'"},{"v":22,"t":"Kad prorok govori u ime Jahve pa to ne bude i riječ se ne ispuni, onda je to riječ koje Jahve nije kazao. U drskosti je taj prorok govorio. Nemoj od njega strahovati."}]},"19":{"hr":[{"v":1,"t":"Kad Jahve, Bog tvoj, istrijebi narode čiju zemlju tebi daje te kad ih istjeraš i nastaniš se u njihovim gradovima i domovima,"},{"v":2,"t":"u zemlji koju ti Jahve, Bog tvoj, daje u baštinu, odvoji tri grada."},{"v":3,"t":"Načini put onamo, a onda područje zemlje koju ti Jahve, Bog tvoj, daje u baštinu podijeli natroje, tako da svaki ubojica može onamo uteći."},{"v":4,"t":"Ovo je slučaj u kojemu ubojica može onamo pobjeći i spasiti svoj život: kad tko ubije svoga bližnjega nehotice, a da ga prije nije mrzio;"},{"v":5,"t":"primjerice, kad ode sa svojim bližnjim u šumu da siječe drva, zamahne sjekirom u ruci da obori drvo, gvožđe odleti s držalice i pogodi njegova druga te on pogine: takav ubojica neka uteče u jedan od tih gradova i spasit će život."},{"v":6,"t":"Inače bi krvni osvetnik, progoneći u svom bijesu ubojicu - kad bi put bio predug - mogao gonjenoga stići i pogubiti ga, iako taj nije zaslužio smrt budući da ubijenoga nije otprije mrzio."},{"v":7,"t":"Stoga ti nalažem: tri grada odvoji!"},{"v":8,"t":"A kad Jahve, Bog tvoj, proširi tvoje područje, kao što se zakleo ocima tvojim, i dadne ti svu zemlju koju je obećao tvojim ocima,"},{"v":9,"t":"budeš li držao i vršio sve ove zapovijedi što ti ih danas nalažem i ljubio Jahvu, Boga svoga, te hodio njegovim putovima sve vrijeme - onda ovim gradovima dodaj još tri grada:"},{"v":10,"t":"tako se neće prolijevati nedužna krv u tvojoj zemlji koju ti Jahve daje u baštinu i nećeš se krvlju okaljati."},{"v":11,"t":"Ali ako tko mrzi svoga bližnjega i vreba ga, skoči na nj i ubije ga, a zatim pobjegne u jedan od tih gradova,"},{"v":12,"t":"onda neka starješine onoga grada izvedu ubojicu i predaju ga u ruke krvnom osvetniku da ga pogubi."},{"v":13,"t":"Neka ga oko tvoje ne sažaljuje! Tako ćeš u Izraelu iskorijeniti prolijevanje nedužne krvi i bit ćeš sretan."},{"v":14,"t":"Nemoj pomicati susjedova međaša kojim su stari razmeđašili tvoj posjed što ćeš ga naslijediti u zemlji koju ti Jahve, Bog tvoj, daje u baštinu."},{"v":15,"t":"Neka ne ustaje jedan jedini svjedok protiv čovjeka ni za koju krivnju i ni za kakav zločin. Kakav god bio prekršaj, neka presuda počiva na iskazu dvojice ili trojice svjedoka."},{"v":16,"t":"Ako kakav krivi svjedok ustane protiv koga optužujući ga za pobunu,"},{"v":17,"t":"onda obojica koja se parbe neka stupe pred Jahvu, pred svećenika i suce koji budu vršili službu u to vrijeme."},{"v":18,"t":"Neka suci provedu temeljitu istragu. Bude li se pokazalo da je svjedok lažan i da je lažno svjedočio protiv svoga brata,"},{"v":19,"t":"učinite mu onako kako je on kanio svome bratu. Iskorijeni zlo iz svoje sredine!"},{"v":20,"t":"Drugi će, kad o tome čuju, pobojati se te više neće činiti takva zla u tvojoj sredini."},{"v":21,"t":"Neka ti se oko ne sažaljuje! Život za život; oko za oko; zub za zub; ruka za ruku; noga za nogu."}]},"20":{"hr":[{"v":1,"t":"Ako pođeš u rat na svoje neprijatelje te vidiš konje, kola i narod brojniji od sebe, ne boj ih se! TÓa s tobom je Jahve, Bog tvoj, koji te izveo iz zemlje egipatske."},{"v":2,"t":"Prije boja neka svećenik istupi i govori narodu."},{"v":3,"t":"Neka im kaže: 'Čuj, Izraele! Danas polazite u boj na neprijatelje svoje. Neka vam srca ne klonu! Ne plašite se! Ne bojte se! Ne dršćite pred njima!"},{"v":4,"t":"TÓa Jahve, Bog vaš, ide s vama da se bori za vas protiv vaših neprijatelja i da vas spasi.'"},{"v":5,"t":"Potom neka narodu progovore nadglednici: 'Ima li koga da je sagradio novu kuću a nije se u nju uselio? Neka se vrati kući svojoj da ne pogine u boju pa da se tko drugi u nju ne useli."},{"v":6,"t":"Ima li koga da je zasadio vinograd a još ga nije brao? Neka se vrati domu svome da u boju ne pogine te da mu drugi roda ne obere."},{"v":7,"t":"Ima li koga da se zaručio a nije se oženio? Neka se vrati domu svome da u boju ne pogine te da mu tko drugi zaručnice ne odvede.'"},{"v":8,"t":"Neka nadglednici nastave te narodu kažu: 'Tko se boji i kome srce trne, neka se vrati domu svome da ne trne srce njegovoj braći kao njemu.'"},{"v":9,"t":"Kad nadglednici završe govor narodu, neka vojni zapovjednici stanu na čelo naroda."},{"v":10,"t":"Kada dođeš pod koji grad da na nj navališ, najprije mu ponudi mir."},{"v":11,"t":"Ako ti odgovori mirom i otvori ti vrata svoja, sav narod što se nađe u njemu podvrgni tlaki neka za te radi."},{"v":12,"t":"Ali ako odbije tvoj mir i zarati s tobom, opsjedni ga."},{"v":13,"t":"Kad ti ga Jahve, Bog tvoj, preda u ruke, sve njegove muškarce pobij oštrim mačem!"},{"v":14,"t":"A žene, djecu, stoku, sve što bude u gradu - sav plijen - uzmi sebi i uživaj plijen od svojih neprijatelja što ti ga daje Jahve, Bog tvoj."},{"v":15,"t":"Tako čini sa svim gradovima koji budu vrlo daleko od tebe, koji ne budu gradovi ovih naroda odavde."},{"v":16,"t":"U gradovima onih naroda koje ti Jahve, Bog tvoj, preda u baštinu ništa ne ostavljaj na životu"},{"v":17,"t":"nego ih udari 'heremom' - kletim uništenjem: Hetite i Amorejce, Kanaance i Perižane, Hivijce i Jebusejce, kako ti je Jahve, Bog tvoj, naredio,"},{"v":18,"t":"tako da vas ne nauče činiti sve one odvratnosti što ih čine svojim bogovima te da ne sagriješite protiv Jahve, Boga svoga."},{"v":19,"t":"Kad navališ na kakav grad pa ga moradneš dugo opsjedati da ga osvojiš, nemoj uništavati njegovih stabala zasijecajući u njih sjekirom. Možeš im jesti plod, a nemoj ih sjeći. Jer poljska stabla nisu ljudi da bi ispred tebe mogla bježati u utvrdu."},{"v":20,"t":"Jedino stabla za koja znaš da nisu voćke možeš ništiti; njih možeš sjeći i od njih praviti naprave za opsadu grada koji je u ratu protiv tebe dok ne padne."}]},"21":{"hr":[{"v":1,"t":"Ako se u zemlji koju ti Jahve, Bog tvoj, daje da je zaposjedneš nađe tko ubijen gdje u polju leži - a ne zna se tko ga je ubio -"},{"v":2,"t":"onda neka odu tvoje starješine i suci te izmjere udaljenost od ubijenoga do okolnih gradova."},{"v":3,"t":"Tako će ustanoviti koji je grad najbliže ubijenom. Starješine toga grada neka tada uzmu junicu što još nije radila: što još pod jarmom nije vukla."},{"v":4,"t":"Neka zatim starješine onoga grada stjeraju junicu u kakav nepresušni potok, na mjesto koje se ne obrađuje i ne zasijava, i ondje, na potoku, neka junicu zakolju."},{"v":5,"t":"Zatim neka dođu svećenici, potomci Levijevi. Jer njih je odabrao Jahve, Bog tvoj, da mu služe i da u ime Jahvino blagoslivljaju; na njihovu se riječ rješava svaki spor i svako nasilje."},{"v":6,"t":"Zatim sve starješine iz onoga grada koji bude najbliži ubijenome neka operu ruke u potoku nad zaklanom junicom."},{"v":7,"t":"Potom neka izjave: 'Naše ruke nisu prolile ove krvi niti smo svojim očima išta vidjeli."},{"v":8,"t":"Zakrili, Jahve, svoj narod Izrael koji si oslobodio; ne dopusti da se prolijeva nedužna krv u tvome izraelskom narodu!' Tako će biti zaštićeni od krvi."},{"v":9,"t":"A ti ćeš ukloniti prolijevanje nedužne krvi iz svoje sredine ako učiniš što je pravo u Jahvinim očima."},{"v":10,"t":"Kad odeš u rat na svoje neprijatelje pa ih Jahve, Bog tvoj, preda u ruke tvoje te ih zarobiš,"},{"v":11,"t":"ako među zarobljenicima opaziš lijepu ženu i u nju se zagledaš, možeš je uzeti za ženu."},{"v":12,"t":"Dovedi je svojoj kući pa neka obrije glavu, obreže nokte"},{"v":13,"t":"i odbaci haljine u kojima je zarobljena. Neka provede mjesec dana u tvome domu oplakujući svoga oca i svoju majku. Poslije toga možeš joj pristupiti kao muž i neka ti postane ženom."},{"v":14,"t":"Ako ti poslije ne bi bila po volji, pusti je kuda joj drago. Za novac je ne smiješ prodati niti s njom postupiti kao s ropkinjom jer ti je bila žena."},{"v":15,"t":"Ako koji čovjek imadne dvije žene: jednu koja mu je draga, a drugu koja mu je mrska, te mu i draga i mrska rode sinove, ali prvorođenac bude od one koja mu je mrska,"},{"v":16,"t":"onda, kad dođe dan da podijeli svoju imovinu među svoje sinove, ne smije postupiti prema prvorođencu od drage na štetu sina od mrske, koji je prvenac,"},{"v":17,"t":"nego mora za prvorođenca priznati sina od mrske i njemu dati dvostruk dio od svega što ima. Jer on je prvina njegove snage - njemu pripada pravo prvorodstva."},{"v":18,"t":"Ako tko imadne opaka i nepokorna sina koji neće da sluša ni oca ni majke - pa ni onda pošto ga kazne -"},{"v":19,"t":"neka ga njegov otac i njegova mati odvedu starješinama svoga grada, na vrata svoga mjesta,"},{"v":20,"t":"i neka kažu gradskim starješinama: 'Ovaj naš sin opak je i nepokoran; neće da nas sluša; ništarija je i pijanica.'"},{"v":21,"t":"Potom neka ga svi ljudi, njegovi sugrađani, kamenjem zasiplju dok ne pogine. Tako ćeš iskorijeniti zlo iz svoje sredine: sav će Izrael to čuti i bojat će se."},{"v":22,"t":"Ako tko učini grijeh koji zaslužuje smrt te bude pogubljen vješanjem o stablo,"},{"v":23,"t":"njegovo mrtvo tijelo neka ne ostane na stablu preko noći nego ga pokopaj istoga dana, jer je obješeni prokletstvo Božje. Tako nećeš okaljati svoje zemlje, koju ti Jahve, Bog tvoj, daje u baštinu."}]},"22":{"hr":[{"v":1,"t":"Kad vidiš kako luta vol ili ovca tvoga brata, nemoj proći mimo njih nego ih otjeraj svome bratu."},{"v":2,"t":"Ako ti brat nije blizu ili ga ne znaš, kući ih svojoj dotjeraj pa neka ostanu kod tebe dokle brat tvoj ne dođe po njih. Tada mu ih vrati."},{"v":3,"t":"Tako čini s njegovim magarcem, s njegovim ogrtačem i sa svime što brat tvoj izgubi, a ti nađeš. Nije ti dopušteno prolaziti mimo njegovo."},{"v":4,"t":"Kad opaziš kako se magarac tvoga brata ili njegov vol svalio na putu, ne kloni se nego mu pomozi da ih podigne."},{"v":5,"t":"Žena ne smije na se stavljati muške odjeće, a muškarac se ne smije oblačiti u ženske haljine. Tko bi to činio bio bi odvratan Jahvi, Bogu svome."},{"v":6,"t":"Ako putem naiđeš na ptičje gnijezdo sa ptićima ili s jajima, na stablu ili na zemlji, a majka bude ležala sa ptićima ili na jajima, nemoj uzimati majke sa ptićima:"},{"v":7,"t":"pusti majku na slobodu, a ptiće uzmi. Tako ćeš imati sreću i dug život."},{"v":8,"t":"Kad gradiš novu kuću, na krovu načini ogradu da svoju kuću, kad bi tko s nje pao, ne okaljaš krvlju."},{"v":9,"t":"Po svome vinogradu nemoj sijati drugog usjeva da ne bi bila posvećena čitava ljetina: i plod sjemena i rod vinograda."},{"v":10,"t":"Ne upreži u plug vola i magarca zajedno."},{"v":11,"t":"Ne oblači se u tkaninu otkanu od vune i lana zajedno."},{"v":12,"t":"Na četiri roglja ogrtača kojim se zaogrćeš napravi rese."},{"v":13,"t":"Ako koji čovjek uzme ženu i uđe k njoj, ali je potom zamrzi,"},{"v":14,"t":"pripiše joj ružnoće i ozloglasi je govoreći: 'Oženih se njome, ali kad joj priđoh, ne nađoh u nje znakova djevičanstva' -"},{"v":15,"t":"neka tada djevojčin otac i majka uzmu dokaz djevojčina djevičanstva te ga iznesu pred gradske starješine na vrata."},{"v":16,"t":"Potom neka progovori starješinama djevojčin otac: 'Ovome sam čovjeku dao svoju kćer za ženu, ali mu je omrzla."},{"v":17,"t":"Stoga joj pripisuje svašta ružno i tvrdi: nisam u tvoje kćeri našao znakove djevičanstva. Ali evo djevičanskih znakova moje kćeri!' I neka razastru plahtu pred gradskim starješinama."},{"v":18,"t":"Neka tada starješine onoga grada uzmu muža pa ga kazne;"},{"v":19,"t":"neka ga, zato što je pronio ružan glas o jednoj izraelskoj djevici, udare globom od stotinu srebrnika pa ih dadnu ocu mlade žene. I neka mu ona i dalje bude ženom da je ne može pustiti dok je živ."},{"v":20,"t":"Ali ako optužba - da se na mladoj ženi nije našlo djevičanstvo - bude istinita,"},{"v":21,"t":"neka djevojku izvedu na kućna vrata njezina oca pa neka je ljudi njezina grada kamenjem zasiplju dok ne umre, jer je počinila besramnost u Izraelu odajući se bludu u očevu domu. Tako ćeš iskorijeniti zlo iz svoje sredine."},{"v":22,"t":"Ako se koji čovjek zateče gdje leži sa ženom udatom za drugoga, neka oboje - i čovjek koji je ležao sa ženom i sama žena - budu smaknuti. Tako ćeš iskorijeniti zlo iz Izraela."},{"v":23,"t":"Ako mladu djevicu zaručenu za nekoga u gradu sretne drugi čovjek i s njom legne,"},{"v":24,"t":"oboje ih dovedite vratima toga grada pa ih kamenjem zasipljite dok ne umru: djevojku što nije zvala u pomoć u gradu, a čovjeka što je oskvrnuo ženu bližnjega svoga. Tako ćeš iskorijeniti zlo iz svoje sredine."},{"v":25,"t":"Ako čovjek u polju naiđe na zaručenu djevojku i silom legne s njom, onda neka se pogubi samo taj što je s njom legao;"},{"v":26,"t":"a djevojci nemoj ništa: nema na njoj krivnje kojom bi zasluživala smrt. Jer to je kao da navali tko na bližnjega svoga i ubije ga."},{"v":27,"t":"On ju je zatekao u polju; i premda je zaručena djevojka zapomagala, nije bilo nikoga da joj priskoči u pomoć."},{"v":28,"t":"Ako čovjek naiđe na mladu djevicu koja nije zaručena te je pograbi i s njom legne, pa budu uhvaćeni na djelu,"},{"v":29,"t":"tada čovjek koji je s njom ležao neka djevojčinu ocu dade pedeset srebrnika. A budući da ju je oskvrnuo, neka je uzme za ženu da je ne može pustiti dok je živ."}]},"23":{"hr":[{"v":1,"t":"Neka se nitko ne ženi ženom oca svoga i neka ne odgrće očeva pokrivača."},{"v":2,"t":"Neka se u Jahvinu zajednicu ne prima onaj komu je stučena mošnjica ili odrezano udo."},{"v":3,"t":"Ni mješanac neka se ne prima u Jahvinu zajednicu; neka se njegovi ne primaju u zajednicu Jahvinu ni do desetog koljena."},{"v":4,"t":"Neka ne ulazi u Jahvinu zajednicu ni Amonac ni Moabac; nitko od njihovih, čak ni u deseto koljeno, ne smije nikad u zajednicu Jahvinu."},{"v":5,"t":"A sve zato što nisu izašli pred vas s kruhom i vodom kad bijaste na putu izišavši iz Egipta; i što su za novce najmili sina Beorova, Bileama iz Petora u Aram Naharajimu, da te prokune."},{"v":6,"t":"Ali Jahve, Bog tvoj, ne htjede uslišati Bileama nego ti Jahve, Bog tvoj, prometnu prokletstvo u blagoslov jer te ljubi Jahve, Bog tvoj."},{"v":7,"t":"Nikad ne promiči njihovo blagostanje i njihovo dobro u sve dane svoje dovijeka."},{"v":8,"t":"Nemoj prezirati Edomca, jer je on brat tvoj. Ne preziri ni Egipćanina, jer si bio došljak u zemlji njegovoj."},{"v":9,"t":"Njihovi potomci u trećem naraštaju mogu se primiti u Jahvinu zajednicu."},{"v":10,"t":"Kad pođeš s taborom na svoje neprijatelje, čuvaj se od svakoga zla."},{"v":11,"t":"Ako je među tvojima tko postao nečist zbog noćnog izljeva, neka iziđe iz tabora i neka se ne vraća u nj."},{"v":12,"t":"A predvečer neka se u vodi opere te u smiraje može opet u tabor."},{"v":13,"t":"Imaj izvan tabora mjesto gdje ćeš ići napolje."},{"v":14,"t":"Sa svojom opremom nosi i lopaticu: njome ćeš, kad ideš napolje, iskopati rupu i poslije zatrpati svoju nečist."},{"v":15,"t":"TÓa Jahve, Bog tvoj, ide posred tvoga tabora da te štiti i da ti predaje neprijatelje. Stoga i tvoj tabor treba da bude svet: neka Jahve ne zapazi u tebe ništa nedolično, da se ne bi odvratio od tebe."},{"v":16,"t":"Ne smiješ gospodaru izručivati roba koji je od svoga gospodara utekao k tebi."},{"v":17,"t":"Neka boravi s tobom u tvojoj sredini, u mjestu što ga odabere u jednome od tvojih gradova gdje mu se svidi. Nemoj s njime loše postupati."},{"v":18,"t":"Neka ne bude svetišne bludnice među izraelskim kćerima i neka ne bude svetišnog bludnika među izraelskim sinovima!"},{"v":19,"t":"Ne donosi u Dom Jahve, Boga svoga, ni za kakav zavjet bludničine plaće ni pasjeg novca, jer je oboje odvratno Jahvi, Bogu tvome."},{"v":20,"t":"Ne traži kamata od svoga brata, niti kamata za novac, niti kamata na jestvine, niti kamata na bilo što gdje se obično traže."},{"v":21,"t":"Od tuđinca možeš tražiti kamate, ali ih od svoga brata nemoj tražiti, da ti Jahve, Bog tvoj, udijeli blagoslov u svakom pothvatu tvoje ruke u zemlji u koju ideš da je zaposjedneš."},{"v":22,"t":"Kad zavjetuješ kakav zavjet Jahvi, Bogu svome, ne oklijevaj da ga ispuniš. Zacijelo će ga Jahve, Bog tvoj, od tebe tražiti; i bio bi ti grijeh."},{"v":23,"t":"Ako se ne zavjetuješ, neće ti biti grijeh."},{"v":24,"t":"Ali ispuni ono što prijeđe preko tvojih usana, zavjet koji si svojim ustima slobodno učinio Jahvi, Bogu svome."},{"v":25,"t":"Ako uđeš u vinograd svoga susjeda, slobodno ti je zobati grožđa do mile volje, ali u svoj sud ne smiješ stavljati."},{"v":26,"t":"Ako uđeš u žito svoga susjeda, možeš kidati klasove rukom, ali ne smiješ prinositi srpa susjedovu žitu."}]},"24":{"hr":[{"v":1,"t":"Kada tko uzme ženu i s njome postupi kao muž, a potom na njoj otkrije što ružno te ona više ne nalazi milosti u njegovim očima i on joj napiše otpusno pismo, uruči joj ga i potjera je iz svoje kuće,"},{"v":2,"t":"a ona izađe iz njegove kuće, ode i pođe za drugoga"},{"v":3,"t":"pa omrzne i tome drugomu te joj i on napiše otpusno pismo, uruči joj ga i otjera je iz svoje kuće - ili pak umre taj koji ju je drugi uzeo -"},{"v":4,"t":"tada je, pošto se tako oskvrnula, ne može opet uzeti za ženu onaj prvi muž koji je bijaše otpustio. Bilo bi to odvratno pred Jahvom; ne smiješ uvaljivati u grijeh zemlju koju ti Jahve, Bog tvoj, daje u baštinu."},{"v":5,"t":"Kad se tko netom oženi, neka ne ide u vojsku; neka mu se ne dodjeljuje nikakva služba, nego, oslobođen, neka ostane kod kuće godinu dana da razveseljuje ženu koju je doveo."},{"v":6,"t":"Neka se ne uzima u zalog žrvanj, ni gornji ni donji: tÓa time bi se u zalog uzimao sam život."},{"v":7,"t":"Ako se nađe tko da otme koga između svoje braće Izraelaca te postupi s njim kao s robom ili ga proda, taj otmičar neka se smakne! Tako ćeš iskorijeniti zlo iz svoje sredine."},{"v":8,"t":"Javi li se guba, pazi da brižno držiš i vršiš sve što vas pouče levitski svećenici. Držite i vršite što njima naredim."},{"v":9,"t":"Sjećaj se što je Jahve, Bog tvoj, učinio Mirjami na putu kad ste izišli iz Egipta."},{"v":10,"t":"Kada bližnjemu svome daješ bilo kakav zajam, nemoj ulaziti u njegovu kuću da mu uzmeš zalog."},{"v":11,"t":"Stoj vani, a čovjek komu si dao zajam neka ti iznese zalog van."},{"v":12,"t":"A ako on bude siromah, nemoj lijegati s njegovim zalogom;"},{"v":13,"t":"o zalasku sunca moraš mu vratiti zalog da on mogne spavati u svome ogrtaču i tebe blagoslivljati. To će ti biti dobro djelo pred Jahvom, Bogom tvojim."},{"v":14,"t":"Nemoj zakidati jadnoga i bijednog najamnika, bio on tvoj sunarodnjak ili došljak iz kojega grada u tvojoj zemlji."},{"v":15,"t":"Svaki dan daj mu zaradu prije nego sunce zađe, jer je siromah i za njom uzdiše. Tako neće na te vapiti Jahvi i nećeš sagriješiti."},{"v":16,"t":"Neka se očevi ne osuđuju na smrt zbog sinova ni sinovi zbog očeva; neka svatko za svoj grijeh gine."},{"v":17,"t":"Ne izvrći pravice došljaku ni siroti i ne uzimaj u zalog haljine udovici."},{"v":18,"t":"Sjećaj se da si bio rob u Egiptu i da te odande izbavio Jahve, Bog tvoj; zato ti nalažem da ovu zapovijed vršiš."},{"v":19,"t":"Kad žanješ žito na svojoj njivi pa zaboraviš koji snop na njivi, ne vraćaj se po nj; neka ostane došljaku, siroti i udovici da te Jahve, Bog tvoj, blagoslovi u svakom pothvatu ruku tvojih."},{"v":20,"t":"Kad jednom omlatiš svoje masline, više iza sebe ne pretražuj; neka to ostane došljaku, siroti i udovici."},{"v":21,"t":"Kad obereš svoj vinograd, ne paljetkuj iza sebe; neka to bude za došljaka, sirotu i udovicu."},{"v":22,"t":"Sjećaj se kako si bio rob u zemlji egipatskoj; zato ti naređujem da ovu zapovijed vršiš."}]},"25":{"hr":[{"v":1,"t":"Kad nastane svađa među ljudima i dođu na sud da im se sudi, neka se dade pravo onome koji je prav, a krivac neka se osudi."},{"v":2,"t":"Ako krivac zasluži da bude išiban, neka mu sudac naredi da legne i tu pred njim neka mu odbroje onoliko udaraca koliko odgovara njegovoj krivnji."},{"v":3,"t":"Do četrdeset udaraca može mu se dati, ali ne više, da modrica ne bi bila prevelika te se ne bi ponizio tvoj brat pred tobom kad bi mu udarali više udaraca."},{"v":4,"t":"Ne zavezuj usta volu kad vrše."},{"v":5,"t":"Kad braća stanuju zajedno pa jedan od njih umre a da nije imao sina, žena pokojnoga neka se ne preudaje izvan kuće, nego neka k njoj pristupi njezin djever i uzme je sebi za ženu te izvrši djeversku dužnost."},{"v":6,"t":"A prvi sin koga ona rodi neka ostane na ime njegova pokojnoga brata da njegovo ime ne izumre u Izraelu."},{"v":7,"t":"Ako, međutim, onaj čovjek ne želi da se oženi svojom snahom, onda njegova snaha neka dođe na vrata pred starješine i kaže: 'Neće djever moj da sačuva ime bratu svome u Izraelu; neće da mi učini djeversku dužnost.'"},{"v":8,"t":"Neka ga pozovu starješine njegova grada i pitaju. Bude li uporan i kaže: 'Ne želim se njom ženiti',"},{"v":9,"t":"neka njegova snaha k njemu pristupi na oči starješine pa mu skine s noge sandalu, pljune mu u lice i kaže ove riječi: 'Ovako se radi čovjeku koji neće da podigne doma svome bratu!'"},{"v":10,"t":"Taj neka se prozove u Izraelu 'Dom bosoga'."},{"v":11,"t":"Ako se dvojica potuku, pa žena jednoga pođe da izbavi svoga muža iz šaka onoga koji ga tuče i pruži ona svoju ruku i onoga uhvati za sram,"},{"v":12,"t":"odsijeci joj ruku i neka je ne sažaljuje oko tvoje."},{"v":13,"t":"U torbi nemoj nositi dvojak uteg, veći i manji."},{"v":14,"t":"U svojoj kući opet nemoj držati dvojaku efu: veću i manju."},{"v":15,"t":"Neka ti je uteg potpun i točan i neka ti je efa potpuna i točna, da dugo živiš na zemlji koju ti daje Jahve, Bog tvoj."},{"v":16,"t":"TÓa Jahvi je, Bogu tvome, odvratan tko to čini, tko god čini nepravdu."},{"v":17,"t":"Sjećaj se onoga što ti je učinio Amalek dok ste bili na putu pošto ste izišli iz Egipta;"},{"v":18,"t":"kako te dočeka na putu i pobi u tvom zaleđu sve nemoćne kad si bio umoran i iscrpljen jer se nije Boga bojao."},{"v":19,"t":"I zato kad te Jahve, Bog tvoj, smiri od svih tvojih neprijatelja naokolo u zemlji koju ti Jahve, Bog tvoj, daje u baštinu, izbriši pod nebom spomen na Amaleka. Ne zaboravi!"}]},"26":{"hr":[{"v":1,"t":"Kad stigneš u zemlju koju ti Jahve, Bog tvoj, daje u baštinu, kad je zaposjedneš i u njoj se nastaniš,"},{"v":2,"t":"uzmi nešto prvina od svakoga ploda što ga budeš dobivao od zemlje koju ti Jahve, Bog tvoj, daje: stavi ih u košaru, otiđi u mjesto što ga Jahve, Bog tvoj, odabere da u njemu nastani svoje ime."},{"v":3,"t":"Stupi k svećeniku koji bude tada vršio službu i reci: 'Priznajem danas pred Jahvom, Bogom svojim, da sam stigao u zemlju za koju se Jahve zakleo našim ocima da će je nama dati.'"},{"v":4,"t":"Zatim će svećenik uzeti iz tvoje ruke košaru i položiti je pred žrtvenik Jahve, Boga tvoga."},{"v":5,"t":"Ti onda nastavi i reci pred Jahvom, Bogom svojim: 'Moj je otac bio aramejski lutalac koji je sa malo čeljadi sišao u Egipat da se skloni. Ali je ondje postao velikim, brojnim i moćnim narodom."},{"v":6,"t":"Egipćani su s nama postupali loše; tlačili su nas i nametnuli nam teško ropstvo."},{"v":7,"t":"Vapili smo Jahvi, Bogu otaca svojih. Jahve je čuo vapaj naš; vidje naš jad, našu nevolju i našu muku."},{"v":8,"t":"Iz Egipta nas izvede Jahve moćnom rukom i ispruženom mišicom, velikom strahotom, znakovima i čudesima."},{"v":9,"t":"I dovede nas na ovo mjesto i dade nam ovu zemlju, zemlju kojom teče med i mlijeko."},{"v":10,"t":"I sad, evo, donosim prvine plodova sa tla što si mi ga, Jahve, dao.' Stavi ih pred Jahvu, Boga svoga, i pred Jahvom, Bogom svojim, duboko se nakloni."},{"v":11,"t":"A onda zajedno s levitom i došljakom koji bude kod tebe uživaj sva dobra kojima je Jahve, Bog tvoj, obasuo tebe i dom tvoj."},{"v":12,"t":"A kad treće godine - godine desetine - završiš odjeljivanje sve desetine od svoga prihoda i dadeš levitu, došljaku, siroti i udovici po tvojim gradovima da jedu do sitosti,"},{"v":13,"t":"tada pred Jahvom, Bogom svojim, izjavi: 'Iz kuće sam uklonio ono što je bilo posvećeno. Dao sam još i levitu, došljaku, siroti i udovici, prema svim tvojim zapovijedima koje si mi izdao. Ni jedne tvoje zapovijedi nisam prekršio ni zaboravio."},{"v":14,"t":"Od toga nisam ništa jeo u žalosti; od toga nisam ništa žrtvovao u nečistoći, niti sam od toga što dao mrtvacu; slušao sam glas Jahve, Boga svoga; u svemu sam učinio kako si mi naredio."},{"v":15,"t":"Pogledaj s nebesa, iz svoga svetog prebivališta, i blagoslovi narod svoj izraelski i zemlju koju si nam dao, zemlju kojom teče med i mlijeko - kako si se zakleo ocima našim.'"},{"v":16,"t":"Jahve, Bog tvoj, naređuje ti danas da vršiš ove zakone i uredbe. Drži ih, dakle, i vrši svim srcem svojim i svom dušom svojom."},{"v":17,"t":"Danas si ugovorio s Jahvom da će ti on biti Bog, a ti da ćeš ići njegovim putovima, držati njegove zakone, njegove zapovijedi i njegove uredbe i slušati njegov glas."},{"v":18,"t":"Danas je Jahve ugovorio s tobom da ćeš ti biti njegov narod, njegova predraga svojina, kako ti je obećao, i da ćeš držati sve njegove zapovijedi."},{"v":19,"t":"On će te uzvisiti čašću, imenom i slavom nad sve narode koje je stvorio; i ti ćeš biti narod posvećen Jahvi, Bogu svome, kako ti je rekao.”"}]},"27":{"hr":[{"v":1,"t":"Potom Mojsije i starješine izraelske nalože narodu: “Vršite sve zapovijedi što vam ih danas naređujem."},{"v":2,"t":"Onog dana kad prijeđete preko Jordana u zemlju što ti je daje Jahve, Bog tvoj, podigni sebi veliko kamenje; krečom ga okreči"},{"v":3,"t":"i na njemu ispiši sve riječi ovoga Zakona u trenutku kad budeš ulazio u zemlju što ti je daje Jahve, Bog tvoj, u zemlju kojom teče med i mlijeko, kako ti je rekao Jahve, Bog otaca tvojih."},{"v":4,"t":"Kada, dakle, prijeđeš preko Jordana, onda to kamenje, kako ti danas zapovijedam, podigni na brdu Ebalu i okreči ga krečom."},{"v":5,"t":"Ondje sagradi i žrtvenik Jahvi, Bogu svome - žrtvenik od kamenja na koje nisi spuštao gvožđa."},{"v":6,"t":"Žrtvenik Jahvi, Bogu svome, sagradi od neklesana kamena. Na njemu prinosi paljenice Jahvi, Bogu svome."},{"v":7,"t":"Prinosi i pričesnice i ondje ih blaguj, radujući se pred Jahvom, Bogom svojim."},{"v":8,"t":"Ispiši na tom kamenju sve riječi ovoga Zakona: ureži ih dobro.”"},{"v":9,"t":"Zatim Mojsije i levitski svećenici rekoše svemu Izraelu: “Pozor, Izraele, i slušaj! Danas si postao narodom Jahve, Boga svoga."},{"v":10,"t":"Zato slušaj glas Jahve, Boga svoga, i vrši zapovijedi njegove i zakone njegove koje ti danas naređujem.”"},{"v":11,"t":"Onoga dana naredi Mojsije narodu:"},{"v":12,"t":"“Kad prijeđete preko Jordana, neka ova plemena: Šimun, Levi, Juda, Jisakar, Josip i Benjamin stanu na brdu Gerizimu da blagoslivljaju narod."},{"v":13,"t":"A ova neka stanu na brdu Ebalu da proklinju: Ruben, Gad, Ašer, Zebulun, Dan i Naftali."},{"v":14,"t":"Neka onda Levijevci preuzmu riječ i jakim glasom reknu svim Izraelcima:"},{"v":15,"t":"'Proklet bio tko načini kumira, klesana ili livena - zazor Jahvi, djelo rukotvorca, sve ako ga stavi i na potajno mjesto.' - I sav narod neka odgovori: 'Amen!'"},{"v":16,"t":"'Proklet bio koji vrijeđa oca svoga i majku svoju!' - I sav narod neka reče: 'Amen!'"},{"v":17,"t":"'Proklet bio koji pomakne međaš susjedov!' - I sav narod neka reče: 'Amen!'"},{"v":18,"t":"'Proklet bio koji slijepca zavede na stranputicu!' - I sav narod neka reče: 'Amen!'"},{"v":19,"t":"'Proklet bio koji krnji prava došljaka, sirote i udovice!' - I sav narod neka reče: 'Amen!'"},{"v":20,"t":"'Proklet bio koji legne sa ženom oca svoga, jer je razgrnuo pokrivač oca svoga!'- I sav narod neka reče: 'Amen!'"},{"v":21,"t":"'Proklet bio koji legne s bilo kakvom životinjom!' - I sav narod neka reče: 'Amen!'"},{"v":22,"t":"'Proklet bio koji legne sa svojom sestrom, bila ona kći njegova oca ili kći njegove majke.' - I sav narod neka reče: 'Amen!'"},{"v":23,"t":"'Proklet bio koji legne s punicom svojom!' - I sav narod neka reče: 'Amen!'"},{"v":24,"t":"'Proklet bio koji ubije bližnjega svoga iz potaje!' - I sav narod neka reče: 'Amen!'"},{"v":25,"t":"'Proklet bio koji primi mito da smrt donese nevinome!' - I sav narod neka reče: 'Amen!'"},{"v":26,"t":"'Proklet bio koji ne bude držao riječi ovoga Zakona i vršio ih!' - I sav narod neka reče: 'Amen!'"}]},"28":{"hr":[{"v":1,"t":"Ako zbilja poslušaš glas Jahve, Boga svoga, držeći i vršeći sve njegove zapovijedi što ti ih danas naređujem, Jahve, Bog tvoj, uzvisit će te nad sve narode na zemlji."},{"v":2,"t":"Svi ovi blagoslovi sići će na te i stići će te ako budeš slušao glas Jahve, Boga svoga."},{"v":3,"t":"Blagoslovljen ćeš biti u gradu, blagoslovljen u polju."},{"v":4,"t":"Blagoslovljen će biti plod utrobe tvoje, rod zemlje tvoje, plod blaga tvoga: mlad krava tvojih i prirast stada tvoga."},{"v":5,"t":"Blagoslovljen će biti tvoj koš i naćve tvoje."},{"v":6,"t":"Blagoslovljen ćeš biti kad ulaziš, blagoslovljen kad izlaziš."},{"v":7,"t":"Neprijatelje tvoje koji se dignu protiv tebe Jahve će položiti preda te potučene; jednim će putem izaći na te, a na sedam putova razbježat će se ispred tebe."},{"v":8,"t":"Jahve će narediti da blagoslov bude s tobom u žitnicama tvojim i u svakom pothvatu ruke tvoje i blagoslivljat će te u zemlji koju ti Jahve, Bog tvoj, daje."},{"v":9,"t":"Jahve će od tebe učiniti narod sebi posvećen, kako ti se zakleo, ako budeš držao zapovijedi Jahve, Boga svoga, i hodio njegovim putovima."},{"v":10,"t":"Svi narodi zemlje vidjet će da je nada te zazvano ime Jahvino te će strahovati od tebe."},{"v":11,"t":"Jahve će te obasuti obilnim dobrima: porodom utrobe tvoje, priraštajem blaga tvoga i rodom s tla tvoga u zemlji za koju se Jahve zakleo ocima tvojim da će ti je dati."},{"v":12,"t":"Jahve će ti otvoriti svoju bogatu riznicu - nebo - da daje kišu tvojoj zemlji u pravo vrijeme i blagoslovi svaki pothvat ruku tvojih. Mnogim ćeš narodima u zajam davati, a sam nećeš uzimati u zajam."},{"v":13,"t":"Jahve će te držati na pročelju, a ne u začelju; uvijek ćeš biti na vrhu, nikad na dnu, ako budeš slušao zapovijedi Jahve, Boga svoga, što ti ih danas naređujem da ih držiš i vršiš."},{"v":14,"t":"Ni od jedne riječi što vam je danas nalažem nemoj odstupati ni desno ni lijevo idući za drugim bogovima i iskazujući im štovanje."},{"v":15,"t":"Ali ako ne budeš slušao glasa Jahve, Boga svoga, ne držeći i ne vršeći svih njegovih zapovijedi i svih njegovih zakona što ti ih danas naređujem, sva će ova prokletstva doći na te i stići će te:"},{"v":16,"t":"Proklet ćeš biti u gradu, proklet u polju."},{"v":17,"t":"Proklet će biti koš tvoj i naćve tvoje."},{"v":18,"t":"Proklet će biti plod utrobe tvoje i rod zemlje tvoje, mlad krava tvojih i priraštaj stada tvoga."},{"v":19,"t":"Proklet ćeš biti kad ulaziš, proklet kad izlaziš."},{"v":20,"t":"Jahve će na te puštati prokletstvo, zabunu i kletvu u svemu na što pružiš ruku svoju da uradiš, sve dok ne budeš satrt i brzo ne propadneš zbog zloće svojih djela kojima si me napustio."},{"v":21,"t":"Kugu će Jahve za te privezati dok te ne nestane sa zemlje u koju ideš da je zaposjedneš."},{"v":22,"t":"Jahve će te udariti sušicom, groznicom, upalom, žegom i sušom, medljikom i snijeti; to će te goniti dok te ne nestane."},{"v":23,"t":"Nebesa nad tvojom glavom postat će mjedena, a tlo pod tvojim nogama postat će gvozdeno."},{"v":24,"t":"Kišu tvoje zemlje Jahve će pretvarati u pijesak i prašinu da na te pada s nebesa dok te ne uništi."},{"v":25,"t":"Jahve će od tebe učiniti pobijeđenoga pred tvojim neprijateljima; jednim ćeš putem prema njima izlaziti, a na sedam putova bježat ćeš ispred njih. Strašilo ćeš postati za sva zemaljska kraljevstva."},{"v":26,"t":"I mrtvo tijelo tvoje postat će hranom svim pticama nebeskim i svoj zvjeradi zemaljskoj. Nikoga neće biti da ih plaši."},{"v":27,"t":"Jahve će te udarati egipatskim prištevima, čirevima, krastama i svrabom, od kojih se nećeš moći izliječiti."},{"v":28,"t":"Jahve će te udarati bjesnilom, sljepoćom i ludilom;"},{"v":29,"t":"u po bijela dana tumarat ćeš kao što tumara slijepac po mraku; nećeš imati uspjeha u svojim pothvatima; sve vrijeme svoje bit ćeš izrabljivan i pljačkan, a neće biti nikoga da te spasi."},{"v":30,"t":"Sa ženom ćeš se zaručivati, ali će je drugi posjedovati. Kuću ćeš graditi, ali u njoj nećeš stanovati. Vinograd ćeš zasađivati, ali ga nećeš brati."},{"v":31,"t":"Tvoga će vola na tvoje oči zaklati, ali ti od njega nećeš jesti; tvoga će magarca ispred tebe otimati, ali ti ga neće vraćati; stado će tvoje neprijatelju tvome predavati, a neće biti nikoga da ti pritekne u pomoć."},{"v":32,"t":"Sinovi tvoji i kćeri tvoje bit će predavani drugome narodu. Oči će tvoje svaki dan kapati gledajući za njima, ali ruka tvoja neće moći ništa."},{"v":33,"t":"Narod koji i ne poznaješ jest će plod sa zemlje tvoje i svu muku tvoju, dok ćeš ti sve vrijeme svoje biti izrabljivan i gažen."},{"v":34,"t":"Ludovat ćeš od prizora što će ih oči tvoje gledati."},{"v":35,"t":"Jahve će te udarati ljutim prištevima po koljenima i po stegnima - od stopala nogu tvojih do tjemena na glavi tvojoj - od kojih se nećeš moći izliječiti."},{"v":36,"t":"Jahve će odvesti i tebe i tvoga kralja, koga budeš postavio nad sobom, među narod nepoznat i tebi i tvojim ocima te ćeš ondje iskazivati štovanje drugim bogovima, drvenim i kamenim."},{"v":37,"t":"Bit ćeš na zgražanje, porugu i ruglo svim narodima među koje te Jahve odvede."},{"v":38,"t":"Mnogo ćeš sjemena bacati u polje, ali ćeš malo žeti jer će ti urod skakavci ogolijevati."},{"v":39,"t":"Vinograde ćeš saditi i obrađivati, ali vina nećeš piti niti ćeš što brati jer će ih crv izjedati."},{"v":40,"t":"Imat ćeš masline po svemu svome području, ali se uljem nećeš mazati jer će ti masline opadati."},{"v":41,"t":"Sinove ćeš i kćeri rađati, ali tvoji neće biti jer će u sužanjstvo odlaziti."},{"v":42,"t":"Sva tvoja stabla i rod sa zemlje tvoje postat će plijenom kukaca."},{"v":43,"t":"Došljak koji bude u sredini tvojoj uzdizat će se nada te, a ti ćeš padati sve niže i niže."},{"v":44,"t":"On će uzaimati tebi, a ne ti njemu; on će biti glava, a ti rep."},{"v":45,"t":"Sva će te ova prokletstva snalaziti, progoniti i doseći dok te ne unište, jer nisi slušao glasa Jahve, Boga svoga, ni držao zapovijedi njegovih i zakona njegovih koje ti je dao."},{"v":46,"t":"Ona će služiti za čudesni znak na tebi i tvome potomstvu zauvijek."},{"v":47,"t":"Budući da nisi htio služiti Jahvi, Bogu svome, vesela i radosna srca zbog obilja svega,"},{"v":48,"t":"služit ćeš neprijatelju svome, koga će Jahve poslati na te, u gladu i žeđi, golotinji i oskudici svakoj. Na tvoju će šiju navaljivati jaram od gvožđa dok te ne satre."},{"v":49,"t":"Jahve će iz daljine, s kraja zemlje, dovesti na te narod koji će sletjeti kao orao. Bit će to narod kojemu jezika nećeš razumjeti;"},{"v":50,"t":"narod bezdušan, koji neće pokazivati obzira prema starima ni smilovanja prema mladima."},{"v":51,"t":"On će ti jesti mlado od tvoga blaga i rod tvoje njive dok te ne uništi; neće ti ostavljati ni žita, ni vina, ni ulja, ni mlado od krave, ni priraštaj od stada, sve dok te ne upropasti."},{"v":52,"t":"Opsjedat će te u svim tvojim gradovima širom zemlje tvoje dok ne obori visoke i utvrđene bedeme u koje si polagao nadu svoju; opsjednut će te u svim gradovima tvojim širom zemlje tvoje koju ti dadne Jahve, Bog tvoj."},{"v":53,"t":"U tjeskobi i jadu, kojima će te neprijatelj tvoj pritisnuti, jest ćeš plod utrobe svoje - meso sinova svojih i kćeri svojih koje ti dadne Jahve, Bog tvoj."},{"v":54,"t":"Čovjek najnježniji i najmekši u tebe zlobnim će okom gledati na vlastitog brata, ženu u svome naručju i djecu svoju što mu preostanu,"},{"v":55,"t":"ne hoteći ni s jednim od njih dijeliti mesa sinova svojih koje bude jeo, jer zbog tjeskobe i jada, kojima će te neprijatelj tvoj pritiskati po svim gradovima tvojim, drugo mu neće preostajati."},{"v":56,"t":"I žena najnježnija i najmekša što bude u tebe - toliko nježna i tankoćutna da se ne usuđuje spustiti stopala na zemlju - zlobnim će okom gledati na muža u svome naručju, i na sina svoga, i na kćer svoju,"},{"v":57,"t":"i na posteljicu svoju što joj iziđe između nogu, i na djecu što ih ima roditi, jer će ih potajno jesti, oskudna u svemu, zbog nevolje i jada kojim će te neprijatelj tvoj pritisnuti po svim gradovima tvojim."},{"v":58,"t":"Ako ne budeš držao i vršio riječi ovoga Zakona što su napisane u ovoj knjizi, ne poštujući ovo slavno i strašno Ime - Jahvu, Boga svoga -"},{"v":59,"t":"Jahve će tebe i tvoje potomstvo teško ošinuti velikim i dugotrajnim bičevima, pogubnim i dugim bolestima."},{"v":60,"t":"Pustit će na te sva zla egipatska kojih si se plašio, i ona će se prilijepiti za te."},{"v":61,"t":"A i svaku drugu bolest i bič, koji nije naveden u knjizi ovoga Zakona, Jahve će na te puštati dok te ne uništi."},{"v":62,"t":"Ostat će vas samo malo, vas što brojni bijaste kao zvijezde nebeske, a sve zato što nisi slušao glasa Jahve, Boga svoga."},{"v":63,"t":"Kako se Jahve nad vama radovao usrećujući vas i množeći, tako će se Jahve radovati nad vama rušeći vas i uništavajući da se iskorijenite sa zemlje u koju idete da je zaposjednete."},{"v":64,"t":"Jahve će vas razbacati po svim narodima, s kraja na kraj zemlje; ondje ćeš iskazivati štovanje drugim bogovima: drvenim i kamenim - koji su bili nepoznati i tebi i tvojim ocima."},{"v":65,"t":"Ali među tim narodima nećeš imati mira; ni tvome stopalu neće biti počivališta, nego će ti ondje Jahve dati srce uznemireno, oči utonule, dušu tjeskobnu."},{"v":66,"t":"Život tvoj visjet će o niti; bojat ćeš se i danju i noću i nećeš biti siguran za život svoj."},{"v":67,"t":"U strahu koji će ti stezati srce i od prizora što će ga oči tvoje gledati, jutrom ćeš govoriti: 'Oh, da je već večer!' a navečer ćeš govoriti: 'Oh, da je već jutro!'"},{"v":68,"t":"U Egipat će te na galijama natrag odvesti Jahve putem za koji sam ti rekao da ga više ne smiješ vidjeti. Ondje ćete se vi sami prodavati svojim neprijateljima za robove i ropkinje, ali neće biti kupca.”"},{"v":69,"t":"To su riječi Saveza što ga propisa Jahve Mojsiju da ga sklopi s Izraelcima u zemlji moapskoj, povrh Saveza što ga je s njima sklopio na Horebu."}]},"29":{"hr":[{"v":1,"t":"Mojsije sazva sav Izrael pa im reče: “Vidjeli ste na rođene oči sve što je Jahve učinio u zemlji egipatskoj faraonu, svim službenicima njegovim i svoj zemlji njegovoj:"},{"v":2,"t":"velike kušnje što su ih vidjele tvoje oči, silne znakove i čudesa!"},{"v":3,"t":"Ali vam ne dade Jahve do danas razuma da shvatite, očiju da vidite ni ušiju da čujete."},{"v":4,"t":"Vodio sam vas pustinjom četrdeset godina; odjeća se na vama nije izderala niti su se sandale na vašim nogama raskidale."},{"v":5,"t":"Kruha niste jeli; vina ni drugoga opojnog pića niste pili, da biste znali da sam ja Jahve, Bog vaš."},{"v":6,"t":"Kad stigoste na novo mjesto, Sihon, kralj hešbonski, i Og, kralj bašanski, iziđoše pred nas u boj, ali smo ih potukli."},{"v":7,"t":"Zauzeli smo njihovu zemlju te je predali u baštinu Rubenovcima, Gadovcima i polovini plemena Manašeova."},{"v":8,"t":"Držite i vršite riječi ovog Saveza da uspijevate u svemu što poduzmete."},{"v":9,"t":"Danas stojite svi pred Jahvom, Bogom svojim: vaši plemenski glavari, vaše starješine i vaši nadglednici, svi muževi Izraela,"},{"v":10,"t":"djeca vaša, žene vaše i došljak koji je u tvome taboru - od onoga koji ti siječe drva do onoga koji ti nosi vodu -"},{"v":11,"t":"da stupite u Savez s Jahvom, Bogom svojim, u Savez zakletvom potvrđen, što ga Jahve, Bog tvoj, danas s tobom sklapa"},{"v":12,"t":"da danas od tebe učini svoj narod i da ti on bude Bog, kako ti je rekao i kako se zakleo tvojim ocima: Abrahamu, Izaku i Jakovu."},{"v":13,"t":"I ne sklapam danas ovaj Savez sa zakletvom samo s vama"},{"v":14,"t":"nego i sa svakim koji danas stoji ovdje s nama pred Jahvom, Bogom našim, i sa svakim koji danas nije ovdje s nama."},{"v":15,"t":"Sami znate kako smo boravili u zemlji egipatskoj i kako smo prošli posred naroda kroz koje ste morali proći."},{"v":16,"t":"Vidjeli ste njihove rugobe, njihove kumire od drveta i kamena, srebra i zlata što ih imaju."},{"v":17,"t":"Neka ne bude među vama čovjeka ni žene, roda ni plemena kojemu bi se srce danas odvratilo od Jahve, Boga našega, pa da ide iskazivati štovanje bogovima onih naroda. Neka ne bude među vama korijena koji rađa otrovom i pelinom."},{"v":18,"t":"Neka se nitko, čuvši riječi ovog prokletstva, ne nada blagoslovu kazujući u svome srcu: 'Bit će mi dobro ako poživim i po prohtjevima srca svoga. Nek' povodanj utaži žeđ!'"},{"v":19,"t":"Takvome neće Jahve nikad oprostiti, nego će se gnjev i ljubomornost Jahvina izliti na tog čovjeka, tako da će se sve prokletstvo zapisano u ovoj knjizi na nj oboriti te će Jahve izbrisati ime njegovo pod nebom."},{"v":20,"t":"Prema svim prokletstvima ovog Saveza, zapisanima u knjizi ovoga Zakona, Jahve će ga odstraniti, na njegovu propast, od svih plemena izraelskih."},{"v":21,"t":"Kasniji naraštaj, sinovi vaši poslije vas, i stranci koji dođu iz daleke zemlje, kad vide zla ove zemlje i bolesti što će ih Jahve pustiti na nju, reći će:"},{"v":22,"t":"'Sva je zemlja njegova samo sumpor i sol; niti se što sije niti što klija; nikakva travka na njoj ne raste; jednaka je srušenoj Sodomi i Gomori, Admi i Sebojimu, što ih Jahve sruši u svojoj ljutini i gnjevu.'"},{"v":23,"t":"I svi će narodi pitati: 'Zašto učini Jahve ovako ovoj zemlji? Kakva je morala biti žestina toga silnoga gnjeva?'"},{"v":24,"t":"Onda će im se reći: 'Jer su ostavili Savez što ga je Jahve, Bog otaca njihovih, bio sklopio s njima kad ih je izveo iz zemlje egipatske;"},{"v":25,"t":"i jer su otišli da iskazuju štovanje drugim bogovima i njima se klanjali, bogovima kojih nisu poznavali i kojih im on nije odredio."},{"v":26,"t":"Zato se Jahvin gnjev izlio na ovu zemlju i palo na nju sve prokletstvo zapisano u ovoj knjizi."},{"v":27,"t":"Jahve ih je iščupao iz njihove zemlje u ljutini, srdžbi i velikom gnjevu te ih bacio u drugu zemlju. Tako je i danas.'"},{"v":28,"t":"Što je sakriveno, pripada Jahvi, Bogu našemu, a objava nama i sinovima našim zauvijek da vršimo sve riječi ovoga Zakona."}]},"30":{"hr":[{"v":1,"t":"Kad te sve ove riječi, blagoslov i prokletstvo što ih danas preda te stavih, snađu i ti ih uzmeš k srcu među svim narodima među koje te Jahve, Bog tvoj, bude protjerao"},{"v":2,"t":"i obratiš se k Jahvi, Bogu svome, i poslušaš - i ti i tvoji sinovi - glas njegov iz svega srca svoga i iz sve duše svoje u svemu što sam ti danas naredio,"},{"v":3,"t":"tada će Jahve, Bog tvoj, vratiti tvoje izgnanike; smilovat će se tebi i opet ćete sabrati između svih naroda među koje te bude rastjerao Jahve, Bog tvoj."},{"v":4,"t":"Ako bi se koji izgnanik tvoj nalazio i na kraju svijeta, i odande će te sabrati Jahve, Bog tvoj - odande će te uzeti."},{"v":5,"t":"Jahve, Bog tvoj, dovest će te u zemlju koju su posjedovali oci tvoji da je ti zaposjedneš; učinit će te sretnijim i brojnijim od očeva tvojih."},{"v":6,"t":"Jahve, Bog tvoj, obrezat će tvoje srce, srce tvoga potomstva, tako da ljubiš Jahvu, Boga svoga, iz svega srca svoga i iz sve duše svoje i da živiš."},{"v":7,"t":"Jahve, Bog tvoj, svalit će sva ova prokletstva na neprijatelje tvoje, na mrzitelje tvoje koji su te progonili."},{"v":8,"t":"A ti ćeš ponovo slušati glas Jahvin i vršiti sve njegove zapovijedi koje ti danas dajem."},{"v":9,"t":"Jahve, Bog tvoj, obilno će te nagrađivati u svakom pothvatu ruku tvojih, u plodu utrobe tvoje, u plodu stoke tvoje i u urodu tvoga plodnog tla; jer Jahve će se opet radovati nad tvojim dobrom, kao što se radovao nad dobrom otaca tvojih,"},{"v":10,"t":"kad poslušaš glas Jahve, Boga svoga, držeći njegove zapovijedi i njegove naredbe zapisane u knjizi ovoga Zakona, to jest kada se obratiš Jahvi, Bogu svome, svim srcem svojim i svom dušom svojom."},{"v":11,"t":"Ova zapovijed što ti je danas dajem nije za te preteška niti je od tebe predaleko."},{"v":12,"t":"Nije na nebesima da bi rekao: 'Tko će se za nas popeti na nebesa, skinuti nam je te nam je objaviti da je vršimo?'"},{"v":13,"t":"Nije ni preko mora da bi mogao reći: 'Tko će preko mora za nas poći, donijeti nam je te nam je objaviti da je vršimo?'"},{"v":14,"t":"Jer, Riječ je posve blizu tebe, u tvojim ustima i u tvome srcu da je vršiš."},{"v":15,"t":"Gledaj! Danas preda te stavljam: život i sreću, smrt i nesreću."},{"v":16,"t":"Ako poslušaš zapovijedi Jahve, Boga svoga, koje ti danas dajem - ako ih poslušaš ljubeći Jahvu, Boga svoga, hodeći njegovim putovima, vršeći njegove zapovijedi, njegove zakone i njegove uredbe, živjet ćeš i razmnožit će te Jahve, Bog tvoj, i blagoslovit će te u zemlji u koju ulaziš da je zaposjedneš."},{"v":17,"t":"Ali ako se srce tvoje odvrati i ne poslušaš, nego zastraniš i budeš se klanjao drugim bogovima i njima iskazivao štovanje,"},{"v":18,"t":"ja vam danas izjavljujem da ćete zaista propasti; nećete dugo živjeti na zemlji u koju ćete, prešavši Jordan, ući da je zaposjednete."},{"v":19,"t":"Uzimam danas za svjedoke protiv vas nebo i zemlju da pred vas stavljam: život i smrt, blagoslov i prokletstvo. Život, dakle, biraj,"},{"v":20,"t":"ljubeći Jahvu, Boga svoga, slušajući njegov glas, prianjajući uz njega, da živiš ti i tvoje potomstvo. TÓa on je život tvoj, tvoj dugi vijek, da bi mirno mogao boraviti na zemlji za koju se Jahve zakle ocima tvojim Abrahamu, Izaku i Jakovu da će im je dati.”"}]},"31":{"hr":[{"v":1,"t":"Mojsije dođe da upravi ove riječi svemu Izraelu:"},{"v":2,"t":"“Meni je danas sto dvadeset godina”, - reče im. “Ne mogu više izlaziti i ulaziti. A Jahve mi je rekao: 'Nećeš prijeći ovog Jordana!'"},{"v":3,"t":"Sam Jahve, Bog tvoj, pred tobom će prijeći; on će pred tobom potući one narode da ih otjerate s posjeda. Jošua će pred tobom ići, kako je Jahve rekao."},{"v":4,"t":"Jahve će postupiti s njima kako je postupio sa Sihonom i Ogom, amorejskim kraljevima, i njihovom zemljom kad ih uništi."},{"v":5,"t":"Pred vas će ih Jahve položiti, a vi ćete s njima postupati prema svim naredbama koje sam vam dao."},{"v":6,"t":"Ohrabrite se i budite odlučni! Ne bojte se i nemojte prÓedati pred njima. TÓa sam Jahve, Bog tvoj, ide s tobom; neće te zapustiti niti će te ostaviti.”"},{"v":7,"t":"Tada Mojsije zovnu Jošuu pa mu reče pred svim Izraelom: “Ohrabri se i budi odlučan! Jer ti ćeš ići s ovim narodom u zemlju za koju se Jahve zakle ocima njihovim da će im je dati; ti ćeš im je predavati u baštinu."},{"v":8,"t":"Sam Jahve ide pred tobom; on će s tobom biti; neće te zapustiti niti će te ostaviti. Ne boj se i ne dršći!”"},{"v":9,"t":"Mojsije napisa ovaj Zakon i predade ga svećenicima, sinovima Levijevim, koji su nosili Kovčeg saveza Jahvina, i svim izraelskim starješinama."},{"v":10,"t":"Mojsije im naredi: “Svake sedme godine - godine oprosne - na Blagdan sjenica,"},{"v":11,"t":"kad dođe sav Izrael da vidi lice Jahve, Boga tvoga, na mjestu koje on odabere, pročitaj ovaj Zakon u nazočnosti svega Izraela."},{"v":12,"t":"Saberi narod - ljude, žene, djecu i došljaka što bude u tvojim gradovima - da čuju i da nauče bojati se Jahve, Boga vašega, pa da drže i vrše sve riječi ovog Zakona."},{"v":13,"t":"Sinovi njihovi, koji to još ne znaju, čut će i naučit će bojati se Jahve, Boga vašega, sve vrijeme dok budete živjeli na zemlji što ćete je, prešavši Jordan, zaposjesti.”"},{"v":14,"t":"Jahve reče Mojsiju: “Evo se bliži vrijeme tvoje smrti. Zovni Jošuu i nađite se u Šatoru sastanka da mu dam zapovijedi.” Mojsije i Jošua dođu u Šator sastanka."},{"v":15,"t":"U Šatoru pokaže se Jahve u stupu od oblaka. Stup od oblaka stajao je na ulazu u Šator."},{"v":16,"t":"Jahve reče Mojsiju: “Evo ćeš naskoro počinuti sa svojim ocima. A narod će se ovaj dići da čini blud idući za tuđim bogovima one zemlje u koju će naskoro ući; mene će napustiti i prekršit će moj Savez što ga s njim sklopih."},{"v":17,"t":"I onda će se izliti moj gnjev na nj. Ostavit ću ih tada i sakriti od njih svoje lice da budu proždirani. Snaći će ih mnoga zla i nevolje i onda će reći: 'Zar me ne snalaze ove nevolje zbog toga što Bog moj nije u mojoj sredini?'"},{"v":18,"t":"A ja ću sasvim sakriti svoje lice u taj dan, zbog svega zla što ga budu činili okrećući se drugim bogovima."},{"v":19,"t":"Pišite sada sebi ovu pjesmu. Neka je nauče Izraelci! Stavi je u njihova usta da mi ova pjesma bude svjedokom protiv Izraelaca."},{"v":20,"t":"Kad ih dovedem u zemlju kojom teče med i mlijeko i za koju se zakleh ocima njihovim i kad se najedu, nasite i ugoje, okrenut će se oni drugim bogovima i njima će iskazivati štovanje; mene će prezreti i prekršiti moj Savez."},{"v":21,"t":"A kad ih snađu mnoge nesreće i nevolje, ova pjesma, jer je njihovo potomstvo neće nikada zaboraviti, pružit će svjedočanstvo protiv njih. Jer znam ja njihove osnove i što već danas snuju, prije nego sam ih i doveo u zemlju koju im pod zakletvom obećah.”"},{"v":22,"t":"Toga dana napisa Mojsije ovu pjesmu i nauči Izraelce pjesmi."},{"v":23,"t":"Nunovu sinu Jošui naloži: “Ohrabri se i budi odlučan! Jer ti ćeš uvesti Izraelce u zemlju za koju sam im se zakleo. I ja ću biti s tobom.”"},{"v":24,"t":"Kad Mojsije napisa riječi ovoga Zakona u knjigu,"},{"v":25,"t":"tada naredi Levijevcima, koji su nosili Kovčeg saveza Jahvina:"},{"v":26,"t":"“Uzmite knjigu ovoga Zakona i položite je uz Kovčeg saveza Jahvina. Neka ondje bude svjedokom protiv tebe!"},{"v":27,"t":"TÓa znam ja tvoju buntovnost i tvoju tvrdu šiju. Evo i danas, dok još s vama živim, bunite se protiv Jahve. A kako li nećete kad ja umrem!"},{"v":28,"t":"Saberite k meni sve starješine svojih plemena i svoje nadglednike da na njihove uši kažem ove riječi te da protiv njih uzmem za svjedoke nebo i zemlju."},{"v":29,"t":"Jer znam ja da ćete se nakon moje smrti izopačiti i skrenuti s puta koji sam vam odredio; nesreća će vas snaći u budućim vremenima kad budete činili što je Jahvi nemilo i gnjevili ga djelima ruku svojih.”"},{"v":30,"t":"A onda, na uši sve zajednice izraelske, Mojsije izgovori do kraja riječi ove pjesme:"}]},"32":{"hr":[{"v":1,"t":"“Slušajte, nebesa, sad ću govoriti; čuj, zemljo, riječi usta mojih!"},{"v":2,"t":"Nek' mi nauk daždi poput kiše, kao rosa riječ nek' moja pada, kao kišica po mladoj zeleni, kao pljusak po travi velikoj!"},{"v":3,"t":"Jer, Jahvino ću ime uznositi, a vi Boga našeg veličajte!"},{"v":4,"t":"On je Stijena, djelo mu je savršeno, jer pravi su svi njegovi putovi. Bog je on vjeran i bez zloće, pravedan je on i pravičan."},{"v":5,"t":"Oni mu se iznevjeriše - nisu mu sinovi, već nakaze sinovske, porod izopačen i prepreden."},{"v":6,"t":"Tako li uzvraćaš Jahvi, narode glupi i bezumni! Nije li on Otac tvoj, Stvoritelj, koji te sazdao, po kom postojiš?"},{"v":7,"t":"Spomeni se dana pradavnih, promotri godine od naraštaja do naraštaja. Oca svoga pitaj, i poučit će te, pitaj starije, pa će ti kazati."},{"v":8,"t":"Kad je Višnji baštinu dijelio narodima, kad je razmještao sinove čovječje, odredi im međe po broju Božjih sinova:"},{"v":9,"t":"tad Jahvu njegov narod zapade, Jakov bi njegova baština."},{"v":10,"t":"U zemlji stepskoj on ga je našao, u pustinjskoj jezivoj pustoši. Obujmio ga, gajio ga i čuvao k'o zjenu oka svoga."},{"v":11,"t":"Poput orla što bdi nad gnijezdom, nad svojim orlićima lebdeći, tako on krila širi, uzima ga, pa ga na svojim nosi perima."},{"v":12,"t":"Jahve sam njega je vodio, tuđeg boga s njim ne bijaše."},{"v":13,"t":"Povede ga po visočjima zemlje, nahrani ga plodovima poljskim, dade mu meda iz pećine i ulja iz tvrde stijene;"},{"v":14,"t":"kravljeg masla i ovčjeg mlijeka s pretilinom jaganjaca, ovnova bašanskih i jaraca, sa salom žitnih bubrega, i napoji ga pjenušavom krvlju grožđa."},{"v":15,"t":"Jeo je Jakov i nasitio se, ugojio se Ješurun pa se uzritao. Udebljao si se, utovio, usalio. Odbacio je Boga koji ga stvori i prezreo Stijenu svog spasenja."},{"v":16,"t":"Tuđim bozima učiniše ga ljubomornim, razjariše ga gnusobama."},{"v":17,"t":"Žrtvovahu zlodusima koji Bog nisu, bogovima kojih ne poznavahu prije, došljacima koji stigoše nedavno i koje oci njihovi ne štovahu."},{"v":18,"t":"Odnemaruješ Stijenu što te na svijet dade, ne sjećaš se više Boga koji te rodi!"},{"v":19,"t":"Vidje to Jahve i u gnjevu svojem odbaci sinove svoje i kćeri."},{"v":20,"t":"Lice ću im svoje sakriti, reče, i vidjet ću što će biti od njih. Jer izopačeno je to koljeno, sinovi u kojima vjernosti nema."},{"v":21,"t":"Ništavnim me bogom na ljubomor potakoše, razdražiše me ništavilima svojim, i ja ću njih ljubomornim učinit', pukom ništavnim, razdražit ću ih glupim nekim narodom!"},{"v":22,"t":"Da, moga gnjeva požar je usplamtio i gorjet će do dubina šeolskih; proždrijet će zemlju i sve što ona rađa, sažeći joj brda do temelja."},{"v":23,"t":"Nevolje na njih ću svaliti, na njih ću svoje istrošiti strijele."},{"v":24,"t":"Od gladi će umirati, ognjica i pošast njih će trovati. Poslat ću na njih zub zvjerinji i otrov zmija što prahom gmižu."},{"v":25,"t":"Vani će mač zatirati djecu, a strava će vladati unutra. Ginut će jednako momak i djevojka, dojenče i starac sjedokos."},{"v":26,"t":"Rekoh: U prah ću ih smrviti, zbrisati im spomen izmed ljudi."},{"v":27,"t":"Ali se bojah ruga dušmanskoga: mogli bi im prevarit' se protivnici, pa da kažu: 'Pobjeda je naša, nije to Jahvina izvela ruka.'"},{"v":28,"t":"Jer narod je to neupućen, oštroumlja u njih nema."},{"v":29,"t":"Da su mudri, već bi se i dosjetili, razabrali što ih očekuje."},{"v":30,"t":"Kako da jedan tisuću u bijeg nagna, i deset tisuća da dvojica gone, da ih Stijena njina nije prodala, da ih Jahve nije izručio?"},{"v":31,"t":"Al' stijena im nije poput naše Stijene; osuđeni su naši neprijatelji."},{"v":32,"t":"Jer trs je njihov od sodomskog trsa i od vinograda gomorskih; grožđe im je grožđe otrovno, grozdovi im grozdovi gorčine;"},{"v":33,"t":"njihovo je vino otrov zmijski, žestok jed otrovnice ljute."},{"v":34,"t":"Al' nije li on u mene poput dragulja, zapečaćen u mojim riznicama?"},{"v":35,"t":"Moja je odmazda i nagrada u vrijeme kad im noga posrne. Jer blizu je dan njihove propasti, udes njihov brzo im se bliži!"},{"v":36,"t":"(Pravdu će Jahve dati svome puku, sažalit se nad slugama svojim.) Vidjet će da im gine snaga, da je i robu i slobodnu kraj."},{"v":37,"t":"Tad će reći: 'Ta gdje su bozi njihovi, gdje stijena kojom se zaklanjahu?"},{"v":38,"t":"Oni što su jeli salo njihovih klanica i pili vino njihovih ljevanica?' Neka se dignu i neka vam pomognu, nek' vam budu zaklonište!"},{"v":39,"t":"Vidite sada da ja, ja jesam, i da drugog Boga pored mene nema! Ja usmrćujem i oživljujem; ja udaram i iscjeljujem (i nitko se iz ruke moje ne izbavlja)."},{"v":40,"t":"Da, svoju ruku ja dižem prema nebu i kažem: Ne bio ja živ vječito"},{"v":41,"t":"ako naoštrivši mač svoj blistavi ne uzmem sud u svoje ruke da svojim odmazdim dušmanima, da naplatim onima koji mene mrze."},{"v":42,"t":"Strijele svoje opojit ću krvlju i mač moj najest će se mesa, krvi ubijenih i zarobljenih, glava dušmanskih vrhovnika."},{"v":43,"t":"Kličite, o nebesa, s njime, obožavajte ga, sinovi Božji! Kličite, puci, s njegovim narodom, uznosite snagu njegovu, poslanici Jahvini. Jer će krv slugu svojih osvetiti, istom mjerom vratit' dušmanima, naplatit će od onih koji njega mrze, očistit' od grijeha zemlju svog naroda.”"},{"v":44,"t":"Dođe Mojsije s Jošuom, sinom Nunovim, te izgovori u uši naroda riječi ove pjesme."},{"v":45,"t":"Kad Mojsije izgovori sve ove riječi svemu Izraelu,"},{"v":46,"t":"reče im: “U srca svoja usadite sve riječi koje danas uzimam za svjedoka protiv vas; naredite sinovima svojim da ih drže vršeći sve riječi ovoga Zakona."},{"v":47,"t":"TÓa nije to za vas prazna riječ jer ona je vaš život. Zbog ove riječi živjet ćete dugo na zemlji koju ćete, prešavši Jordan, zaposjesti.”"},{"v":48,"t":"Toga istog dana Jahve reče Mojsiju:"},{"v":49,"t":"“Popni se na goru Nebo u Abarskom gorju - ono je u moapskoj zemlji nasuprot Jerihonu - pa pogledaj zemlju kanaansku što ću je dati u posjed Izraelcima."},{"v":50,"t":"Onda umri na gori na koju se uspneš i pridruži se svojim precima kao što je i tvoj brat Aron, koji je umro na brdu Horu, bio pridružen svojima."},{"v":51,"t":"A to zato što ste mi se iznevjerili sred Izraelaca kod Meriba Kadeša, kod voda u pustinji Sinu: niste očitovali moju svetost među Izraelcima."},{"v":52,"t":"Zato ćeš samo izdaleka vidjeti onu zemlju, ali u nju nećeš ući - u zemlju koju dajem Izraelcima.”"}]},"33":{"hr":[{"v":1,"t":"Ovo je blagoslov kojim Mojsije - čovjek Božji - blagoslovi Izraelce pred svoju smrt."},{"v":2,"t":"Reče on: “Dođe Jahve sa Sinaja, sa Seira im se pokaza i s gore Parana zasja. Zbog njih dođe od kadeških zborova, sa svoga juga sve do Obronaka."},{"v":3,"t":"Ipak ti ljubiš narode, svi sveti njihovi u tvojoj su ruci. Pred tvojim su ležali nogama, išli tobom predvođeni.”"},{"v":4,"t":"(Mojsije nam je odredio zakon.) “Zbor Jakovljev njegovom posta baštinom;"},{"v":5,"t":"i bje kralj u Ješurunu kad se sakupiše glavari narodni, kad se sjediniše plemena Jakovljeva."},{"v":6,"t":"Nek' živi Ruben i nikad nek' ne izumre, nek' živi šačica njegovih!"},{"v":7,"t":"Evo što reče za Judu: Uslišaj, Jahve, glas Judin i privedi ga k njegovu narodu. Nek mu ruke njegovo brane pravo, pomozi mu protiv dušmana njegovih."},{"v":8,"t":"O Leviju reče: Daj Leviju tvoje Urime i tvoje Tumime čovjeku milosti svoje, koga si u Masi iskušao, s kojim si se preo kod voda meripskih."},{"v":9,"t":"O ocu svome i majci reče on: Nisam ih vidio! Braće svoje ne poznaje, na svoju se djecu ne osvrće, jer tvoju riječ on je vršio i tvojega se držao Saveza."},{"v":10,"t":"On uči Jakova tvojim odredbama i Izraela tvojemu Zakonu. On podiže kad k tvojim nosnicama i paljenicu na žrtvenik ti stavlja."},{"v":11,"t":"O Jahve, snagu mu blagoslovi, milostivo primi djelo ruku njegovih. Slomi bedra njegovih neprijatelja; mrzitelji njegovi nek' više ne ustanu."},{"v":12,"t":"O Benjaminu reče: Jahvin je on ljubimac i u miru svagda počiva. Višnji ga štiti svih njegovih dana, između njegovih prebiva bregova."},{"v":13,"t":"O Josipu reče: Zemlju mu je Jahve blagoslovio; njegovo je najbolje od onog što daje rosa nebeska i što se u bezdanima dolje krije!"},{"v":14,"t":"Najbolje od onog što daruje sunce i što mlađak novi nosi,"},{"v":15,"t":"prvine s drevnih planina i najbolje s vječnih brežuljaka,"},{"v":16,"t":"ponajbolji rod zemlje i svega što je na njoj i milost Onog što prebiva u grmu. Nek' sve to dođe na glavu Josipovu, na tjeme posvećenog između sve braće!"},{"v":17,"t":"K'o prvenac bika on je veličanstven, rozi su mu rogovi bivolji, njima on nabada narode sve do krajeva zemaljskih. Takva su mnoštva Efrajimova, takve su tisuće Manašeove."},{"v":18,"t":"O Zebulunu reče: Bio sretan, Zebulune, u pohodima, i ti, Jisakare, u šatorima svojim!"},{"v":19,"t":"Na brdu gdje dolaze zazivati narodi za uspjeh prinose oni prave žrtve jer sišu obilje mora i blago skriveno u pijesku."},{"v":20,"t":"O Gadu reče: Nek' je blagoslovljen tko Gada raširi! Poput lavice on počiva razderavši mišicu i glavu."},{"v":21,"t":"Prvine je tad sebi dodijelio jer vidje da mu je sačuvan dio glavarev. Na čelu svega naroda on je došao, pravdu Jahvinu izvršivši i odluke njegove s Izraelom."},{"v":22,"t":"O Danu reče: Dan je lavić što skače iz Bašana."},{"v":23,"t":"O Naftaliju reče: Naftali, milostima nasićen, Jahvinim ispunjen blagoslovom: more i jug njegovo su vlasništvo."},{"v":24,"t":"O Ašeru reče: Blagoslovljen bio Ašer među sinovima! Nek' miljenik bude među braćom svojom, i nek' noge svoje u ulje umače!"},{"v":25,"t":"Nek' ti zasuni budu od gvožđa i mjedi i nek' ti mir traje koliko i život!"},{"v":26,"t":"Nitko nije kao Bog Ješurunov: po nebesima u pomoć ti jezdi i po oblacima u svom veličanstvu!"},{"v":27,"t":"Bog vječni tvoje je utočište, a na zemlji drevna njegova mišica pred tobom goni neprijatelja; on dovikuje: 'Uništi!'"},{"v":28,"t":"U sigurnosti prebiva Izrael, a Jakovljev je izvor na osami u zemlji žita i vina, gdje nebesa rosom dažde."},{"v":29,"t":"Blago tebi, Izraele! Koji narod k'o tebe Jahve spasava? On štit je tvoj što te brani i mač tvoj slavodobitni, dušmani ti se ulaguju, al' ti ćeš im gazit' po leđima.”"}]},"34":{"hr":[{"v":1,"t":"Poslije toga ode Mojsije s Moapskih poljana na brdo Nebo, na vrhunac Pisge nasuprot Jerihonu, gdje mu Jahve pokaza svu zemlju: Gilead do Dana,"},{"v":2,"t":"sav Naftali, kraj Efrajimov i Manašeov, svu Judinu krajinu do Zapadnog mora;"},{"v":3,"t":"zatim Negeb, područje doline Jerihona - grada palmi - do Soara."},{"v":4,"t":"Potom mu reče Jahve: “Ovo je zemlja za koju sam se zakleo Abrahamu, Izaku i Jakovu da ću je dati tvome potomstvu. Dopustio sam da je pogledaš svojim očima, ali ti onamo nećeš prijeći.”"},{"v":5,"t":"I Mojsije, sluga Jahvin, umrije ondje u zemlji moapskoj po Jahvinoj zapovijedi."},{"v":6,"t":"I ukopa ga on u dolini u zemlji nasuprot Bet Peoru. Do dana današnjega nitko nije doznao za njegov grob."},{"v":7,"t":"Mojsiju bijaše sto dvadeset godina kad umrije. Oko mu nije oslabilo niti mu je snaga popustila."},{"v":8,"t":"Izraelci oplakivahu Mojsija na Moapskim poljanama trideset dana. Potom prođoše i dani oplakivanja - tugovanja za Mojsijem."},{"v":9,"t":"A Jošua, sin Nunov, bio je ispunjen duhom mudrosti jer Mojsije bijaše na nj položio svoje ruke. Njega su Izraelci slušali i činili kako je Jahve naredio Mojsiju."},{"v":10,"t":"Ne pojavi se više prorok u Izraelu ravan Mojsiju - njega je Jahve poznavao licem u lice! -"},{"v":11,"t":"po svim onim znakovima i čudesima u zemlji egipatskoj za koja ga je Jahve slao da ih učini na faraonu, na svim službenicima njegovim i na svoj zemlji njegovoj,"},{"v":12,"t":"po onoj moćnoj ruci njegovoj i po svim onim velikim zastrašnim djelima koja učini na oči svega Izraela."}]}},"JOS":{"1":{"hr":[{"v":1,"t":"Poslije smrti Mojsija, sluge Jahvina, reče Jahve Jošui, sinu Nunovu, pomoćniku Mojsijevu:"},{"v":2,"t":"“Moj je sluga Mojsije umro; zato sada ustani, prijeđi preko toga Jordana, ti i sav taj narod, u zemlju koju dajem sinovima Izraelovim."},{"v":3,"t":"Svako mjesto na koje stupi vaša noga dajem vam, kao što obećah Mojsiju."},{"v":4,"t":"Od pustinje i od Libanona pa do Velike rijeke, rijeke Eufrata, i sve do Velikog mora na sunčanom zapadu - sve će to biti vaše područje."},{"v":5,"t":"Nitko neće odoljeti pred tobom u sve dane tvog života; ja ću biti s tobom, kao što sam bio s Mojsijem, i nikada te neću napustiti niti ću te ostaviti."},{"v":6,"t":"Budi odvažan i hrabar jer ćeš ti uvesti narod ovaj da primi u baštinu zemlju za koju se zakleh ocima njihovim da ću im je dati."},{"v":7,"t":"Samo budi odvažan i hrabar da sve učiniš vjerno prema naredbama koje ti je dao Mojsije, sluga moj. Ne skreći od toga ni desno ni lijevo da bi ti bilo sretno sve što poduzmeš."},{"v":8,"t":"Neka knjiga Zakona bude na ustima tvojim: razmišljaj o njoj danju i noću, kako bi vjerno držao sve što je u njoj napisano: samo ćeš tada biti sretan i uspjet ćeš u pothvatima. Nisam li ti zapovjedio:"},{"v":9,"t":"odvaži se i budi hrabar? Ne boj se i ne strahuj, jer kuda god pođeš, s tobom je Jahve, Bog tvoj.”"},{"v":10,"t":"Tada zapovijedi Jošua glavarima narodnim:"},{"v":11,"t":"“Prođite kroz tabor i proglasite puku ovu zapovijed: 'Spremite sebi brašnenice jer ćete za tri dana prijeći preko Jordana da biste primili u posjed zemlju koju vam Jahve, Bog vaš, daje u baštinu.'”"},{"v":12,"t":"Zatim reče Jošua plemenu Rubenovu i Gadovu i polovini plemena Manašeova:"},{"v":13,"t":"“Sjetite se onoga što vam je zapovjedio Mojsije, sluga Jahvin, kada vam je rekao: 'Jahve, Bog vaš, hoće da počinete i daje vam ovu zemlju."},{"v":14,"t":"Vaše žene, djeca i stada mogu ostati u zemlji koju vam je dao Mojsije s onu stranu Jordana. Vi pak ratnici, za boj spremni, morate naoružani poći pred svojom braćom da im pomognete,"},{"v":15,"t":"sve dok Jahve ne dade da počinu i vaša braća, kao i vi, i dok ne zaposjednu zemlju koju im daje Jahve, Bog vaš. Tada se možete vratiti u zemlju koja vam pripada i koju vam je dao Jahvin sluga Mojsije, na drugoj strani Jordana, prema istoku sunca.'”"},{"v":16,"t":"Oni odgovore Jošui: “Sve što nam zapovjediš, učinit ćemo, i kuda nas god pošalješ, poći ćemo."},{"v":17,"t":"Kao što smo slušali Mojsija, tako ćemo se pokoravati i tebi. Samo neka Jahve, Bog tvoj, bude s tobom kao što bijaše s Mojsijem!"},{"v":18,"t":"Tko se god usprotivi tvome glasu i ne posluša tvojih riječi u svemu što mu zapovjediš neka bude pogubljen. Samo ti budi odvažan i hrabar!”"}]},"2":{"hr":[{"v":1,"t":"Jošua, sin Nunov, posla potajno iz Šitima dvojicu uhoda s nalogom: “Idite, izvidite područje, osobito Jerihon.” Oni odu i stignu u kuću bludnice koja se zvala Rahaba i ondje prenoće."},{"v":2,"t":"To bude javljeno kralju jerihonskom: “Evo, stigoše noćas ovamo neki ljudi od sinova Izraelovih da izvide zemlju.”"},{"v":3,"t":"Tada kralj jerihonski poruči Rahabi: “Izvedi ljude koji su došli k tebi, koji su ušli u tvoj dom, jer su došli uhoditi svu zemlju.”"},{"v":4,"t":"Ali žena uze ona dva čovjeka, sakri ih i reče: “Istina, ti su ljudi došli k meni, ali ja nisam znala odakle su."},{"v":5,"t":"Kada se u sumrak zatvarahu gradska vrata, oni odoše i ja ne znam kamo su krenuli. Požurite za njima jer ih još možete stići.”"},{"v":6,"t":"A ona ih bijaše izvela na krov i sakrila pod netrveni lan što ga je ondje razastrla."},{"v":7,"t":"I požure se ljudi u potjeru za njima, prema Jordanu, sve do prijelaza preko rijeke; a kad je potjera izišla, zatvore se za njima gradska vrata."},{"v":8,"t":"Dok još oni gore ne bijahu zaspali, popne se Rahaba k njima na krov"},{"v":9,"t":"i reče im: “Znam da vam je Jahve dao ovu zemlju, jer nas je sve uhvatio strah od vas i prezaju od vas svi žitelji ovoga kraja."},{"v":10,"t":"Jer čusmo kako je Jahve isušio vodu Crvenoga mora pred vama kada ste izašli iz Egipta, i ono što ste učinili dvojici kraljeva amorejskih s druge strane Jordana, Sihonu i Ogu, koje pogubiste."},{"v":11,"t":"Kad smo čuli sve to, zastalo nam srce i nitko da smogne snage da vam se suprotstavi jer Jahve, Bog vaš - on je Bog gore na nebesima i dolje na zemlji."},{"v":12,"t":"Zakunite mi se, dakle, Jahvom da ćete i vi učiniti milost domu oca moga, kao što i ja učinih milost vama, i dajte mi pouzdan znak"},{"v":13,"t":"da ćete ostaviti na životu moga oca i moju majku, braću moju i sestre moje i sve njihovo i da ćete nas izbaviti od smrti.”"},{"v":14,"t":"Odgovoriše joj ljudi: “Životom svojim jamčimo za vas, samo ako nas ne izdate. Kad nam Jahve dade zemlju, iskazat ćemo ti milost i vjernost.”"},{"v":15,"t":"Rahaba ih zatim spusti po konopu kroz prozor jer joj je kuća bila uz bedem i ona je do bedema stanovala."},{"v":16,"t":"Još im reče: “Pođite prema gori da vas potjera ne nađe i krijte se ondje tri dana dok se progonitelji ne vrate, a onda idite svojim putem.”"},{"v":17,"t":"Ljudi joj odgovore: “Evo, ovako ćemo ti ispuniti zakletvu kojom si nas zaklela:"},{"v":18,"t":"kad uđemo u zemlju, posluži se ovim znakom: priveži ovu crvenu vrpcu za prozor kroz koji nas spuštaš i sakupi kod sebe, u kući, svoga oca, i svoju majku, i svoju braću, i svu svoju rodbinu."},{"v":19,"t":"Tko god od vas stupi van preko praga tvoje kuće, krv njegova na glavu njegovu: nije krivnja na nama - sam je krivac svojoj smrti; a tko ostane s tobom u kući, krv njegova neka padne na glave naše - mi ćemo biti krivci ako ga se tko rukom dotakne."},{"v":20,"t":"Ako pak izdaš ovu našu stvar, slobodni smo od zakletve kojom si nas zaklela.”"},{"v":21,"t":"A ona odgovori: “Neka bude kako rekoste!” Tada ih pusti i oni odoše, a ona zaveza na prozor crvenu vrpcu."},{"v":22,"t":"Oni odoše i dođoše u goru i ondje ostadoše tri dana dok se ne vrati potjera; tražila ih je potjera na svim putovima, ali ih nije nigdje našla."},{"v":23,"t":"Tada se vrate i one dvije uhode: siđu s gore, prijeđu preko rijeke i dođu k Jošui, sinu Nunovu, te ga izvijeste o svemu što im se dogodilo."},{"v":24,"t":"I rekoše Jošui: “Jahve nam je svu tu krajinu predao u ruke; sve je njezine stanovnike uhvatio strah pred nama.”"}]},"3":{"hr":[{"v":1,"t":"Urani Jošua i sa svim sinovima Izraelovim krene od Šitima. I stignu do Jordana pa ondje prije prelaza prenoće."},{"v":2,"t":"Poslije tri dana prođu starješine kroz tabor i zapovjede puku:"},{"v":3,"t":"“Čim ugledate Kovčeg saveza Jahve, Boga vašega, i svećenike levite koji ga nose, krenite svi sa svoga mjesta i pođite za njim."},{"v":4,"t":"Tako ćete znati put kojim vam je ići, jer tim putem još nikada niste išli. Ali između vas i Kovčega neka bude razmak do dvije tisuće lakata. I da mu se niste približili.”"},{"v":5,"t":"A Jošua zapovjedi narodu: “Posvetite se za sutra, jer će sutra Jahve učiniti čudesa među vama.”"},{"v":6,"t":"A svećenicima Jošua zapovjedi: “Dignite Kovčeg saveza i nosite ga pred narodom.” I digoše Kovčeg saveza i poniješe ga pred narodom."},{"v":7,"t":"Jahve reče Jošui: “Danas te počinjem uzvisivati pred očima svega Izraela, neka znaju da sam s tobom kao što bijah s Mojsijem."},{"v":8,"t":"Ti pak zapovjedi svećenicima koji nose Kovčeg saveza:' Kada stignete do voda jordanskih, u Jordanu se samom zaustavite.'”"},{"v":9,"t":"Tada reče Jošua Izraelcima: “Priđite i čujte riječi Jahve, Boga svojega.”"},{"v":10,"t":"I reče Jošua: “Po ovomu ćete spoznati da je među vama Bog živi: on će goniti ispred vas Kanaance, Hetite, Hivijce, Perižane, Girgašane, Amorejce i Jebusejce."},{"v":11,"t":"Evo, Kovčeg saveza Gospodara sve zemlje proći će pred vama preko Jordana."},{"v":12,"t":"Izaberite odmah dvanaest ljudi iz plemena Izraelovih, po jednoga iz svakoga plemena."},{"v":13,"t":"Čim stopala svećenika koji nose Kovčeg Jahve, Gospodara sve zemlje, stupe u Jordan, razdijelit će se voda Jordana, i ona što teče odozgo ustavit će se kao nasip.'”"},{"v":14,"t":"Kad je narod krenuo iz svojih šatora da prijeđe preko Jordana, ponesu svećenici Kovčeg saveza pred njim."},{"v":15,"t":"A kad su nosači Kovčega stigli do Jordana i kada su svećenici koji su nosili Kovčeg zagazili u vodu na obali - a bilo je vrijeme žetve kad se Jordan prelijeva preko svojih obala -"},{"v":16,"t":"voda što je tekla odozgo daleko se, poput nasipa, ustavila kod grada Adame, koji se nalazi kraj Sartana; a voda što je otjecala dolje u Arabsko ili Slano more sasvim je otekla i narod je prelazio prema Jerihonu."},{"v":17,"t":"Svećenici koji su nosili Kovčeg saveza Jahvina stajahu na suhu usred Jordana i prelažaše Izrael po suhu sve dok sav narod ne prijeđe preko rijeke."}]},"4":{"hr":[{"v":1,"t":"Pošto je sav narod prešao preko Jordana, reče Jahve Jošui:"},{"v":2,"t":"“Izaberite iz naroda dvanaest ljudi, od svakoga plemena po jednoga,"},{"v":3,"t":"i zapovjedite im: 'Dignite odavde, iz sredine Jordana - s mjesta gdje stoje noge svećenika - dvanaest kamenova koje ćete ponijeti sa sobom i položiti na mjestu gdje budete noćas prenoćili.'”"},{"v":4,"t":"Tada pozva Jošua dvanaest ljudi koje je bio izabrao između sinova Izraelovih, iz svakoga plemena po jednoga čovjeka,"},{"v":5,"t":"i reče im: “Idite pred Kovčeg Jahve, Boga svoga, u sredinu Jordana, i neka svaki donese na svojim ramenima po jedan kamen prema broju plemena Izraelovih."},{"v":6,"t":"To će biti na spomen među vama. Kad vas jednoga dana budu pitala vaša djeca: 'Što vam znače ovi kamenovi?'"},{"v":7,"t":"reći ćete im: 'Voda se Jordana razdijelila pred Kovčegom saveza Jahvina kad je prelazio preko Jordana.' I ovo će kamenje biti vječni spomen sinovima Izraelovim.”"},{"v":8,"t":"Izraelci učine kako im je zapovjedio Jošua, uzmu dvanaest kamenova iz sredine Jordana, prema broju plemena Izraelovih, kako je Jahve naredio Jošui: prenesu ih do svoga noćišta i polože ondje."},{"v":9,"t":"Zatim Jošua postavi usred Jordana dvanaest kamenova na mjesta gdje su stajale noge svećenika koji su nosili Kovčeg saveza. Ondje stoje i danas."},{"v":10,"t":"Svećenici koji su nosili Kovčeg saveza stajali su usred Jordana, sve dok se nije izvršilo sve što je Jahve zapovjedio Jošui da narod izvrši, sasvim onako kao što Mojsije bijaše naredio Jošui. A narod je žurno prelazio."},{"v":11,"t":"Pošto je sav narod prešao, prijeđu i svećenici s Kovčegom saveza Jahvina i krenu pred narodom."},{"v":12,"t":"Tada sinovi Rubenovi i sinovi Gadovi i polovina plemena Manašeova u bojnoj opremi stanu na čelo sinova Izraelovih, kao što im bijaše zapovjedio Mojsije."},{"v":13,"t":"Oko četrdeset tisuća naoružanih ljudi prešlo je pred Jahvom da se bori na Jerihonskim poljanama."},{"v":14,"t":"Toga dana uzvisi Jahve Jošuu pred svim Izraelom i svi ga se bojahu, kao nekoć Mojsija, u sve dane njegova života."},{"v":15,"t":"Jahve reče Jošui:"},{"v":16,"t":"“Zapovjedi svećenicima koji nose Kovčeg saveza neka izađu iz Jordana.”"},{"v":17,"t":"Tada Jošua zapovjedi svećenicima: “Izađite iz Jordana!”"},{"v":18,"t":"A čim su svećenici koji su nosili Kovčeg saveza Jahvina izašli isred Jordana i stali nogama na suho, vrate se vode Jordana na svoje mjesto i poteku kao i prije preko svojih obala."},{"v":19,"t":"Narod je izašao iz Jordana desetog dana prvoga mjeseca. Tada se utaborio u Gilgalu, istočno od Jerihona."},{"v":20,"t":"A onih dvanaest kamenova što su ih uzeli sa sobom iz Jordana, Jošua postavi u Gilgalu."},{"v":21,"t":"Tada reče Izraelcima: “Ako potomci vaši upitaju jednoga dana svoje očeve: 'Što znači ovo kamenje?' -"},{"v":22,"t":"vi ih poučite ovako: 'Izrael je ovdje po suhu prešao preko Jordana"},{"v":23,"t":"jer je Jahve, Bog vaš, osušio pred vama vodu Jordana dok ne prijeđoste, kao što je učinio Jahve, Bog vaš, s Morem crvenim kad ga je osušio pred nama dok ne prijeđosmo."},{"v":24,"t":"A sve to, da bi znali svi narodi zemlje koliko je moćna ruka Jahvina, i vi sami da se svagda bojite Jahve, Boga svoga.'”"}]},"5":{"hr":[{"v":1,"t":"Pošto su čuli svi kraljevi amorejski na zapadnoj strani Jordana i svi kraljevi kanaanski koji bijahu uz more da je Jahve osušio Jordan pred Izraelcima dok ne prijeđoše, zastade im srce i nestade im junaštva pred Izraelcima."},{"v":2,"t":"U to vrijeme Jahve reče Jošui: “Načini sebi kamene noževe i ponovo obreži Izraelce.”"},{"v":3,"t":"Jošua načini sebi kamene noževe i obreza Izraelce na brežuljku Aralotu."},{"v":4,"t":"A evo zašto ih je Jošua obrezao: sve ljudstvo što je izišlo iz Egipta, sve što mogaše nositi oružje, pomrlo je na putu kroz pustinju."},{"v":5,"t":"Svi oni bijahu obrezani, ali nije bio obrezan nitko koji se rodio na putu kroz pustinju, poslije izlaska iz Egipta,"},{"v":6,"t":"jer su četrdeset godina Izraelci lutali pustinjom dok ne pomriješe svi za oružje sposobni koji bijahu izišli iz Egipta; nisu slušali glasa Jahvina te im se Jahve zakleo da njihove oči neće vidjeti zemlju koju je obećao njihovim ocima - zemlju u kojoj teče mlijeko i med."},{"v":7,"t":"Na njihovo je mjesto podigao sinove njihove i njih je Jošua obrezao: nisu bili obrezani jer se na putu nije obrezivalo."},{"v":8,"t":"Kad je bio obrezan sav narod, počivali su u taboru sve dok nisu ozdravili."},{"v":9,"t":"Tada reče Jahve Jošui: “Danas skidoh s vas sramotu egipatsku.” I prozva se ono mjesto Gilgal sve do naših dana."},{"v":10,"t":"Izraelci se, dakle, utaboriše u Gilgalu i ondje na Jerihonskim poljanama proslaviše Pashu uvečer četrnaestoga dana u mjesecu."},{"v":11,"t":"A sutradan poslije Pashe, upravo toga dana, blagovali su od uroda one zemlje: beskvasna kruha i pržena zrnja."},{"v":12,"t":"I mÓana je prestala padati čim su počeli jesti plodove zemlje. Tako Izraelci nisu više imali mane, nego su se te godine hranili plodovima zemlje kanaanske."},{"v":13,"t":"Kad se Jošua približio gradu Jerihonu, podiže oči i ugleda čovjeka kako pred njim stoji s isukanim mačem u ruci. Jošua mu pristupi i upita ga: “Jesi li ti s nama ili s našim neprijateljima?”"},{"v":14,"t":"A on odgovori: “Ne, ja sam vođa vojske Jahvine i upravo sam došao ...” Tada Jošua pade ničice, pokloni mu se i reče: “Što zapovijedaš Gospodaru, sluzi svome?”"},{"v":15,"t":"A vođa vojske Jahvine odgovori Jošui: “Skini obuću s nogu svojih, jer je sveto mjesto na kojem stojiš.” I Jošua učini tako."}]},"6":{"hr":[{"v":1,"t":"A Jerihon stajaše silno utvrđen i zatvoren pred sinovima Izraelovim. Nitko nije izlazio niti je tko ulazio."},{"v":2,"t":"Tada Jahve reče Jošui: “Evo, predajem ti u ruke Jerihon i kralja njegova s ratnicima."},{"v":3,"t":"Svi vi ratnici obiđite oko grada jedanput na dan. Tako činite šest dana."},{"v":4,"t":"A sedam svećenika neka nose pred Kovčegom sedam truba od ovnujskih rogova. Sedmoga dana obiđite sedam puta oko grada, a svećenici neka trube u trublje."},{"v":5,"t":"Pa kad otežući zatrube u rog ovnujski, neka sav narod, čim čuje glas trube, podigne silnu bojnu viku. I srušit će se gradski bedemi, a narod neka tada ulazi svaki odande gdje se nađe.”"},{"v":6,"t":"Jošua, sin Nunov, pozva k sebi svećenike i reče im: “Uzmite Kovčeg saveza, a sedam svećenika neka ponese sedam truba od rogova ovnujskih pred Kovčegom Jahvinim.”"},{"v":7,"t":"A narodu reče: “Pođite i obiđite oko grada, a ratnici neka idu pred Kovčegom Jahvinim.”"},{"v":8,"t":"I bi kako je Jošua zapovjedio narodu. Pođe sedam svećenika noseći trube od rogova ovnujskih: trubili su u rogove, a Kovčeg Jahvin iđaše za njima."},{"v":9,"t":"Ratnici pođoše pred svećenicima koji su trubili u trube, a zalaznica krenu za Kovčegom. Stupali su tako dok se glas truba razlijegao."},{"v":10,"t":"A narodu bijaše zapovjedio Jošua govoreći: “Ne vičite i ne dajte glasa od sebe i nijedna riječ neka se ne čuje iz vaših usta dok vam ne kažem: 'Vičite!' Tada neka odjekne bojna vika.”"},{"v":11,"t":"I naredi da Kovčeg Jahvin obiđe jednom oko grada pa da se vrate u tabor i ondje prenoće."},{"v":12,"t":"Sutradan urani Jošua, a svećenici ponesu Kovčeg saveza."},{"v":13,"t":"A sedam svećenika koji su nosili sedam truba od rogova ovnujskih pođu pred Kovčegom Jahvinim. Idući trubili su u trube, ratnici iđahu pred njima, a zalaznica pak za Kovčegom Jahvinim dok su trube odjekivale."},{"v":14,"t":"Tako i drugog dana obiđu jednom oko grada pa se vrate natrag u tabor. Tako su činili šest dana."},{"v":15,"t":"A sedmoga dana zorom ustanu i obiđu oko grada istim onakvim redom sedam puta. Samo su toga dana obišli oko grada sedam puta."},{"v":16,"t":"Za sedmog obilaska snažno zatrube svećenici u rogove, a Jošua reče narodu: “Kličite bojne poklike jer vam je Jahve predao grad!"},{"v":17,"t":"Grad neka bude 'herem' Jahvi - uklet i predan uništenju sa svime što je u njemu. Samo bludnica Rahaba da ostane živa i svi koji budu s njom u kući, jer je ona sakrila uhode koje smo poslali."},{"v":18,"t":"A čuvajte se svega ukletog u gradu da i sami ne budete prokleti što ste uzeli ukleto, jer biste time navukli prokletstvo na tabor i unesrećili ga."},{"v":19,"t":"Zato sve srebro i zlato, sve bakreno i željezno posuđe neka bude posvećeno Jahvi i pohranjeno u riznicu.”"},{"v":20,"t":"Tada povika narod i odjeknuše trube. Kada se zaori glas truba i bojni povici naroda, padoše bedemi i narod prodrije u grad, svatko odande gdje se našao, i osvojiše ga."},{"v":21,"t":"I tada izvršiše kletvu ništeći oštricom mača sve što bijaše u gradu: muško i žensko, staro i mlado, volove, ovce i magarad."},{"v":22,"t":"A onoj dvojici što su uhodili zemlju reče Jošua: “Idite u kuću one bludnice pa izvedite ženu sa svima njezinima, kako joj se zakleste.”"},{"v":23,"t":"I mladi ljudi, uhode, odoše te izvedoše Rahabu, njezina oca i njezinu majku, braću i svu rodbinu. Izvedoše sve njezine i smjestiše ih izvan izraelskog tabora."},{"v":24,"t":"Spališe grad i sve što bijaše u njemu: uzeše samo srebro, zlato, tučano i željezno posuđe i staviše u riznicu Doma Jahvina."},{"v":25,"t":"Ali bludnicu Rahabu, svu njenu obitelj i sve njihovo poštedi Jošua. Ona ostade među Izraelcima sve do danas, jer je sakrila glasnike koje je poslao Jošua da uhode Jerihon."},{"v":26,"t":"Tada izreče Jošua ovu kletvu: “Proklet bio pred licem Jahve čovjek koji pokuša da ponovo gradi Jerihon: gradio mu temelje na svom prvencu, podizao mu vrata na svome mezimcu!”"},{"v":27,"t":"Jahve je bio s Jošuom te se pronio glas o njemu po svoj zemlji."}]},"7":{"hr":[{"v":1,"t":"Ali se sinovi Izraelovi teško ogriješiše o “herem”, jer je Akan, sin Karmija, sina Zabdijeva, sina Zerahova, od plemena Judina, uzeo od ukletih stvari, i Jahve se razgnjevi na sinove Izraelove."},{"v":2,"t":"Jošua pak posla ljude iz Jerihona u Aj, koji leži istočno od Betela, i reče im: “Uziđite onamo, izvidite kraj!” Ljudi odoše te izvidješe Aj."},{"v":3,"t":"Vrativši se k Jošui, rekoše mu: “Ne treba da onamo uzlazi sav narod; dvije do tri tisuće ljudi neka idu da osvoje Aj. Ne muči onamo sav narod, jer je ondje malo svijeta.”"},{"v":4,"t":"Pođe onamo oko tri tisuće ljudi od svega naroda, ali su morali pobjeći pred onima iz Aja."},{"v":5,"t":"Ajani pobiše oko trideset i šest ljudi i tjerali su ih ispred svojih vrata do Šebarima: pobili su ih na strmini. Klonu tada srce narodu kao da mu je voda u žilama."},{"v":6,"t":"Razdrije Jošua haljine svoje i baci se ničice pred Kovčegom Jahvinim, i ostade tako do večeri, on i starješine u Izraelu, posuvši glave pepelom."},{"v":7,"t":"Tada reče Jošua: “Jao, Gospode Jahve, zašto si preveo ovaj narod preko Jordana? Da nas predaš u ruke Amorejaca da nas pobiju? Kamo sreće da smo stali s onu stranu Jordana!"},{"v":8,"t":"Oprosti, Gospode! Što drugo da rečem kad je Izrael okrenuo leđa pred svojim neprijateljima?"},{"v":9,"t":"Ako to čuju Kanaanci i ostali žitelji zemlje, udružit će se protiv nas da zbrišu ime naše sa zemlje. Što ćeš, dakle, učiniti za veliko ime svoje?”"},{"v":10,"t":"A Jahve odgovori Jošui: “Ustani! Zašto si pao ničice?"},{"v":11,"t":"Izrael je sagriješio: prekršili su Savez kojim sam ih vezao. Zaista, uzeše ukleto, porobiše, posakrivaše i prisvojiše."},{"v":12,"t":"I zato Izraelci ne mogu izdržati pred svojim neprijateljima, okreću leđa pred protivnicima jer su postali ukleti. Ja ne mogu više biti s vama ako iz svoje sredine ne maknete proklete."},{"v":13,"t":"Ustani! Sazovi narod na posvećenje i reci mu: Posvetite se za sutra, jer ovako govori Jahve, Bog Izraelov: 'Kletva je u tebi, Izraele; i nećeš izdržati pred svojim neprijateljima sve dok ne odstranite kletvu iz svoje sredine.'"},{"v":14,"t":"Zato sutra zorom pristupite pleme za plemenom; iz plemena koje odredi Jahve prići će rod za rodom, a onda iz roda koji označi Jahve pristupit će obitelj po obitelj, a iz obitelji koju označi Jahve pristupit će čovjek za čovjekom."},{"v":15,"t":"I tko se tada nađe s ukletom stvari, neka se spali on i sve što mu pripada, jer je prekršio Savez Jahvin i osramotio Izraela.”"},{"v":16,"t":"Urani Jošua ujutro i pozva Izraela po plemenima; pristupiše i otkri se pleme Judino."},{"v":17,"t":"Potom pristupi rod za rodom iz plemena Judina i pronađe se rod Zerahov. Pristupiše obitelji roda Zerahova, domaćin jedan za drugim, i pronađoše obitelj Zabdijevu."},{"v":18,"t":"Naposljetku naredi Jošua da pristupi obitelj Zabdijeva, muškarac jedan za drugim, i pronašao se Akan, sin Karmija, sina Zabdijeva, sina Zerahova, od plemena Judina."},{"v":19,"t":"Tada reče Jošua Akanu: “Sine moj, daj slavu Jahvi, Bogu Izraelovu, i priznaj mu što si učinio; objasni što si učinio i nemoj mi ništa tajiti.”"},{"v":20,"t":"Akan reče Jošui: “Zaista, ja sagriješih Jahvi, Bogu Izraelovu, i evo što sam učinio:"},{"v":21,"t":"vidjeh u plijenu lijep šinearski plašt, dvije stotine srebrnjaka i zlatnu šipku vrijednu pedeset srebrnjaka, pa se polakomih i uzeh sebi. Eno je sve zakopano usred moga šatora, a srebro je odozdo.”"},{"v":22,"t":"Tada uputi Jošua poslanike, koji otrčaše u šator. I gle, sve bijaše zakopano u šatoru, a odozdo srebro."},{"v":23,"t":"Uzmu sve iz šatora i donesu Jošui i starješinama Izraelovim i prostriješe sve pred Jahvu."},{"v":24,"t":"Tada uze Jošua Akana, sina Zerahova, i srebro, plašt i zlatnu šipku, i sve sinove i kćeri njegove, volove njegove i magarad, i ovce, šator njegov i sve što bijaše njegovo te ga izvede u dolinu Akor. Pratio ih sav Izrael."},{"v":25,"t":"Reče Jošua: “Kako si ti nas unesrećio, tako danas tebe unesrećio Jahve!” I kamenova ga sav Izrael."},{"v":26,"t":"Potom navališe na njega gomilu kamenja, koje stoji do danas. Tako se Jahve ublaži od svoga žestoka gnjeva. Zbog toga se događaja prozva ono mjesto dolina Akor i tako se zove do danas."}]},"8":{"hr":[{"v":1,"t":"Tada reče Jahve Jošui: “Ne boj se i ne strahuj! Uzmi sa sobom sve ratnike, ustani i navali na Aj. Gle, predajem ti u ruke ajskoga kralja, njegov narod, grad i zemlju njegovu."},{"v":2,"t":"Učini s Ajem i s njegovim kraljem kao što si učinio s Jerihonom i njegovim kraljem; ali vam je slobodno da prigrabite plijen iz njega i njegovu stoku. Postavi gradu zasjedu s leđa.”"},{"v":3,"t":"Spremi se Jošua da navali na Aj i svi ratnici s njime. Izabrao je trideset tisuća junaka i poslao ih noću;"},{"v":4,"t":"dade im zapovijed: “Pazite! Poći ćete u zasjedu gradu s leđa, ali da ne budete predaleko od grada i budite svi spremni."},{"v":5,"t":"A ja i sav narod koji me prati primaknut ćemo se gradu; i kada ljudi iz Aja izađu pred nas, mi ćemo kao i prije pobjeći ispred njih."},{"v":6,"t":"Oni će onda navaliti za nama dok ih ne odvedemo od grada jer će misliti: 'Bježe ispred nas kao i prije.'"},{"v":7,"t":"Tada provalite iz zasjede i zauzmite grad: Jahve, Bog vaš, predat će vam ga u ruke."},{"v":8,"t":"Kad jednom osvojite grad, spalite ga ognjem. Učinite to po Jahvinoj zapovijedi. Pazite, to vam zapovjedih.”"},{"v":9,"t":"Jošua ih posla i oni odoše u zasjedu te se smjestiše između Betela i Aja, gradu sa zapada. A Jošua provede noć među narodom."},{"v":10,"t":"Uranivši, Jošua ujutro prebroja narod i pođe sa starješinama Izraelovim pred narodom na Aj."},{"v":11,"t":"Svi ratnici krenu s njim i kad se primaknu gradu, utabore se Aju sa sjevera, tako da je između njih i mjesta bila ravnica."},{"v":12,"t":"Jošua uze oko pet tisuća ljudi i namjesti zasjedu između Betela i Aja, gradu sa zapadne strane."},{"v":13,"t":"A narod se smjesti u tabor, koji je bio na sjeveru grada, dok je njegova zalaznica bila na zapadu grada. Jošua opet provede noć usred naroda."},{"v":14,"t":"Kad je sve to vidio ajski kralj, požuri se te izađe on i sav njegov narod niz obronak prema Arabi u boj protiv Izraela. A nisu ni slutili da je iza grada namještena zasjeda."},{"v":15,"t":"Tada Jošua i sav Izrael nagnu bježati kao da su ih pobijedili. I bježali su putem prema pustinji."},{"v":16,"t":"Ajani nato pozvaše sve iz grada i dadoše se za njima u potjeru te, goneći Jošuu, odvoje se od grada."},{"v":17,"t":"I ne ostade nitko u Aju i Betelu da nije pošao za Izraelcima. Ostavili su grad otvoren i gonili Izraelce."},{"v":18,"t":"Tada reče Jahve Jošui: “Zamahni kopljem što ti je u ruci prema Aju: predajem ti ga u ruke.” I podiže Jošua koplje što mu bješe u ruci i zamahnu prema gradu."},{"v":19,"t":"I tek što je podigao ruku, dignu se ljudi iz zasjede i potrče prema gradu, osvoje ga i umah ga ognjem zapale."},{"v":20,"t":"Kada se oni iz Aja obazreše, imadoše što vidjeti: dim se dizao iz grada prema nebu. I nitko od njih nije imao kuda uteći ni tamo ni amo. Tada se narod koji je bježao prema pustinji okrenuo prema progoniteljima."},{"v":21,"t":"Vidjevši Jošua i sav Izrael da je zasjeda zauzela grad i da se diže dim iz grada, vrate se i udare na ljude iz Aja."},{"v":22,"t":"Njihovi su im izašli u susret iz grada, i tako se oni iz Aja nađoše posred Izraelaca, opkoljeni i s jedne i s druge strane: biše pobijeni tako te ni jedan ne ostade živ niti uteče."},{"v":23,"t":"A kralja Aja uhvatiše živa i dovedoše ga Jošui."},{"v":24,"t":"Kad su Izraelci pobili sve stanovnike Aja na otvorenu polju i u pustinji, kuda su ih gonili, i kada svi padoše od mača, vratiše se Izraelci u Aj i sasjekoše mačem sve što bješe u njemu."},{"v":25,"t":"Bilo je dvanaest tisuća onih koji su izginuli toga dana, ljudi i žena - sav Aj."},{"v":26,"t":"Jošua nije spuštao ruke kojom bijaše zamahnuo kopljem sve dok nisu poubijani svi stanovnici Aja."},{"v":27,"t":"Samo stoku i plijen iz onoga grada razdijele među sobom Izraelci, kao što je Jahve zapovjedio Jošui."},{"v":28,"t":"Jošua spali Aj i učini ga za sve vijeke ruševinom, pustim mjestom do danas."},{"v":29,"t":"Kralja ajskoga objesi o drvo do večeri. O zapadu sunčanom zapovjedi Jošua te skinuše truplo s drveta, baciše ga pred gradska vrata i nabacaše na nj veliku gomilu kamenja, koja stoji i danas."},{"v":30,"t":"Tada podiže Jošua žrtvenik Jahvi, Bogu Izraelovu, na gori Ebalu,"},{"v":31,"t":"kao što je zapovjedio Mojsije, sluga Jahvin, svim sinovima Izraelovim i kako je napisano u Mojsijevoj knjizi Zakona: žrtvenik od grubog kamena, neklesanog željezom. Na njemu bi prinesena Jahvi žrtva paljenica i pričesnica."},{"v":32,"t":"Tu na kamenju Jošua prepiše Zakon Mojsijev koji bješe napisan za sinove Izraelove."},{"v":33,"t":"I sav Izrael i njegove starješine, glavari narodni i suci, došljaci i domaći, stanu s obje strane Kovčega prema svećenicima i levitima koji su nosili Kovčeg saveza Jahvina - polovina prema gori Gerizimu, a polovina prema gori Ebalu - da bi se blagoslovio puk Izraelov prema obredu koji zapovjedi Mojsije."},{"v":34,"t":"Tada pročita Jošua svaku riječ Zakona, blagoslov i prokletstvo, sve kako je napisano u knjizi Zakona."},{"v":35,"t":"Nije Jošua propustio nijedne Mojsijeve naredbe, nego ih je sve pročitao pred saborom svih Izraelaca, pred ženama, djecom i došljacima koji su išli s njima."}]},"9":{"hr":[{"v":1,"t":"O tim su događajima čuli svi kraljevi s onu stranu Jordana - u Gorju, u Šefeli i duž čitave obale Velikoga mora sve do Libanona: Hetiti, Amorejci, Kanaanci, Perižani, Hivijci, Jebusejci -"},{"v":2,"t":"pa se svi udružiše da složno udare protiv Jošue i Izraela."},{"v":3,"t":"A stanovnici Gibeona, poučeni onim što Jošua učini Jerihonu i Aju,"},{"v":4,"t":"dosjete se lukavstvu. Uzmu hiniti da su putnici: bace na svoje magarce stare vreće i vinske mješine, poderane i zakrpane."},{"v":5,"t":"Obuli su na noge rabljenu i pokrpanu obuću i vrgli na se staru odjeću. Sav kruh što su ga ponijeli na put bijaše suh i razdrobljen."},{"v":6,"t":"Stigoše Jošui u gilgalski tabor i rekoše njemu i ljudima Izraelcima: “Dolazimo iz daleke zemlje, sklopite savez s nama.”"},{"v":7,"t":"Ali ljudi Izraelci kažu tim Hivijcima: “Tko zna ne živite li možda među nama? Kako ćemo, dakle, sklopiti savez s vama?”"},{"v":8,"t":"A oni odgovore Jošui: “Tvoje smo sluge!” Jošua ih upita: “Tko ste i odakle dolazite?”"},{"v":9,"t":"Odgovore: “Daleka je zemlja iz koje dolaze tvoje sluge u ime Jahve, Boga tvojega: čuli smo za slavu njegovu i za sve što je učinio u Egiptu"},{"v":10,"t":"i za ono što je učinio dvojici kraljeva amorejskih koji su vladali s onu stranu Jordana - Sihonu, kralju hešbonskom, i Ogu, kralju bašanskom u Aštarotu."},{"v":11,"t":"Tada nam rekoše naše starješine i svi u našoj zemlji: 'Opskrbite se hranom za put, pođite im u susret i recite im: Vaše smo sluge, sklopite dakle savez s nama.'"},{"v":12,"t":"Evo našega kruha: vruć smo ponijeli na put od kuća svojih kada smo krenuli k vama, a sada je, evo, suh i razdrobljen."},{"v":13,"t":"A ovo su vinski mjehovi: nove smo ih nalili, pa su se, evo, već poderali; i haljine naše i obuća već su trošni od dalekog puta.”"},{"v":14,"t":"I povjerovaše im ljudi po putnoj opskrbi, ne pitajući Jahvu što će im reći."},{"v":15,"t":"Jošua uglavi s njima mir i sklopi savez s njima da će ih poštedjeti. I glavari se na to zakunu."},{"v":16,"t":"A poslije tri dana, pošto su sklopili s njima savez, saznalo se da su im susjedi i da žive usred Izraela."},{"v":17,"t":"Tada krenu Izraelci iz tabora i stignu u njihove gradove, a to su bili Gibeon, Kefira, Beerot i Kirjat Jearim."},{"v":18,"t":"Ali ih nisu napali sinovi Izraelovi, jer su im se glavari zajednice zakleli Jahvom, Bogom Izraelovim. Ali sva zajednica poče rogoboriti protiv glavara."},{"v":19,"t":"Tada svi glavari rekoše zajednici: “Mi smo im se zakleli Jahvom, Bogom Izraelovim, i zato ih ne smijemo dirati."},{"v":20,"t":"Evo što ćemo: pustimo ih da žive, kako nas ne bi stigla srdžba zbog zakletve kojom smo se zakleli.”"},{"v":21,"t":"Još dometnuše glavari: “Neka žive i neka budu drvosječe i vodonoše svoj zajednici.” Sva zajednica prihvati što rekoše glavari."},{"v":22,"t":"Jošua pozva Gibeonce i reče im: “Zašto nas prevariste govoreći: 'Vrlo smo daleko od vas', kad eto živite usred nas?"},{"v":23,"t":"Zato će sada na vama biti kletva i nikada neće nestati među vama ropstva: bit ćete drvosječe i vodonoše za Dom Boga moga.”"},{"v":24,"t":"Oni odgovore Jošui: “Sa svih strana dolazili su glasovi nama, slugama tvojim, kako je Jahve, Bog tvoj, odredio Mojsiju, sluzi svomu, da će vam dati svu zemlju i da će istrijebiti ispred vas sve stanovnike ove zemlje; silno smo se uplašili od vas za svoje živote i zato smo učinili ovo."},{"v":25,"t":"I sada smo, evo, u tvojim rukama: učini s nama što misliš da je dobro i pravo.”"},{"v":26,"t":"A on im je učinio ovako: izbavio ih iz ruku sinova Izraelovih te ih nisu pobili."},{"v":27,"t":"I od toga dana naredi im Jošua da sijeku drva i nose vodu, sve do danas, za zajednicu i za žrtvenik Jahvin na mjestu koje se god izabere."}]},"10":{"hr":[{"v":1,"t":"A kad ču jeruzalemski kralj Adoni-Sedek da je Jošua zauzeo Aj i da ga je izručio “heremu”, kletom uništenju, kao što je učinio s Jerihonom i njegovim kraljem, i da su stanovnici Gibeona učinili mir s Izraelom i uključili se među njih,"},{"v":2,"t":"vrlo se uplaši, jer je Gibeon bio značajan kao kakav kraljevski grad, veći od Aja, a svi žitelji njegovi bijahu ratnici."},{"v":3,"t":"Zato jeruzalemski kralj Adoni-Sedek poruči Hohamu, kralju hebronskom, Piramu, kralju jarmutskom, Jafiji, kralju lakiškom, i Debiru, kralju eglonskom:"},{"v":4,"t":"“Dođite k meni i pomozite mi da udarimo na Gibeon, jer je učinio mir s Jošuom i Izraelcima!”"},{"v":5,"t":"Udruži se tada pet kraljeva amorejskih: kralj jeruzalemski, kralj hebronski, kralj jarmutski, kralj lakiški i kralj eglonski; krenu oni i sva njihova vojska, opsjednu grad Gibeon i počnu ga napadati."},{"v":6,"t":"Tada Gibeonci poručiše Jošui u tabor u Gilgalu: “Ne napuštaj svojih slugu, nego se požuri k nama da nas izbaviš i da nam pomogneš, jer su se protiv nas udružili svi amorejski kraljevi koji žive u Gorju.”"},{"v":7,"t":"I pođe Jošua iz Gilgala, a s njim i svi ratnici, sve vrsni junaci."},{"v":8,"t":"A Jahve reče Jošui: “Ne boj se! Ja sam ih predao u tvoje ruke i nijedan od njih neće se održati pred tobom.”"},{"v":9,"t":"I udari na njih Jošua iznenadno, pošto je svu noć išao od Gilgala."},{"v":10,"t":"I smete ih Jahve pred Izraelcima, koji ih teško poraziše kod Gibeona i potjeraše prema strmini kojom se uzlazi u Bet-Horon. Tukli su ih sve do Azeke i do Makede."},{"v":11,"t":"A dok su bježali pred Izraelom uz bethoronsku strminu, bacao je Jahve s neba na njih tuču kamenja sve do Azeke te su ginuli. I poginulo ih je više od tuče kamene nego što su ih pobili sinovi Izraelovi svojim mačevima."},{"v":12,"t":"Onoga dana kada Jahve predade Amorejce sinovima Izraelovim, obrati se Jošua Jahvi i poviče pred Izraelcima: “Stani, sunce, iznad Gibeona, i mjeseče, iznad dola Ajalona!”"},{"v":13,"t":"I stade sunce i zaustavi se mjesec sve dok se nije narod osvetio neprijateljima svojim. Ne piše li to u knjizi Pravednika? I stade sunce nasred neba i nije se nagnulo k zapadu gotovo cio dan."},{"v":14,"t":"Nije bilo takva dana ni prije ni poslije da bi se Jahve odazvao glasu čovječjem. Tako je Jahve vojevao za Izraela."},{"v":15,"t":"Potom se vrati Jošua i sav Izrael s njim u tabor gilgalski."},{"v":16,"t":"A onih pet kraljeva uteče i sakri se u pećinu kod Makede."},{"v":17,"t":"Javiše Jošui: “Otkriveno je pet kraljeva sakrivenih u pećini kod Makede.”"},{"v":18,"t":"A Jošua reče: “Navalite veliko kamenje pećini na otvor i postavite ljude pred nju da je čuvaju."},{"v":19,"t":"A vi se drugi ne zadržavajte, nego tjerajte svoje neprijatelje i tucite ih s leđa; ne dajte im da uđu u svoje gradove, jer ih Jahve, Bog vaš, predade u vaše ruke.”"},{"v":20,"t":"A kad Jošua i sinovi Izraelovi okončaše bitku teškim pokoljem - utekla im je samo nekolicina preživjelih u tvrde gradove -"},{"v":21,"t":"vrati se narod zdrav i čitav k Jošui u tabor u Makedi. I nitko više ni da pisne protiv sinova Izraelovih."},{"v":22,"t":"Tada reče Jošua: “Otvorite ulaz u pećinu i odande mi izvedite onih pet kraljeva.”"},{"v":23,"t":"I učine tako, izvedu k njemu iz pećine onih pet kraljeva: kralja jeruzalemskoga, kralja hebronskoga, kralja jarmutskoga, kralja lakiškog i kralja eglonskog."},{"v":24,"t":"A kad ih izvedoše, pozva Jošua sve Izraelce i reče vojskovođama koji su ga pratili: “Priđite i stanite svojim nogama na vratove ovih kraljeva.” Oni pristupe i stanu im svojim nogama na vratove."},{"v":25,"t":"Reče Jošua: “Ne bojte se i ne plašite se! Hrabri budite i odlučni, jer će tako Jahve učiniti sa svim vašim neprijateljima s kojima se budete borili.”"},{"v":26,"t":"Potom Jošua naredi da ih pogube i objese na pet stabala; i visjeli su ondje do večeri."},{"v":27,"t":"A o zalasku sunčanom zapovjedi Jošua te ih skidoše s drveća i baciše u istu onu pećinu u koju se bijahu sklonili te na otvor navališe golemo kamenje, koje je i danas ondje."},{"v":28,"t":"Istoga dana zauze Jošua Makedu: udari na grad oštricom mača i pogubi kralja njegova i sve živo u gradu izruči “heremu”, kletom uništenju, ne puštajući da itko utekne. I učini s kraljem makedskim kao što je učinio s kraljem jerihonskim."},{"v":29,"t":"Ode zatim Jošua i sav Izrael iz Makede u Libnu i udari na nju."},{"v":30,"t":"I nju Jahve i njena kralja predade u ruke Izraelu, koji oštricom mača pobi sve živo u njoj; ne poštedje nikoga, a s kraljem Libne učini što i s kraljem jerihonskim."},{"v":31,"t":"Potom ode Jošua i svi Izraelci iz Libne u Lakiš, opsjede ga i napade."},{"v":32,"t":"Jahve predade Lakiš u ruke Izraela, koji ga osvoji sutradan: pobiše oštricom mača sve živo u njemu, onako kao što su učinili s Libnom."},{"v":33,"t":"Tada ustade Horam, kralj Gezera, da pomogne Lakišu, ali Jošua porazi njega i njegov narod tako te nitko ne preživje."},{"v":34,"t":"Jošua krenu zatim sa svim Izraelcima od Lakiša na Eglon. Opsjedoše grad i napadoše ga."},{"v":35,"t":"Osvojiše ga još istoga dana i pobiše sve oštricom mača. Sve živo izručiše kletom uništenju, kako su učinili s Lakišem."},{"v":36,"t":"Onda Jošua sa svim Izraelom krenu od Eglona na Hebron i napade ga."},{"v":37,"t":"Osvojiše ga i pobiše sve oštricom mača, kralja i stanovništvo u svim mjestima koja mu pripadaju, ne poštedjevši nikoga. Učini s njime kao s Eglonom. Grad sa svim svojim stanovništvom bi izručen kletom uništenju."},{"v":38,"t":"Napokon krenu Jošua i sav Izrael s njim na Debir i napadoše ga."},{"v":39,"t":"Osvojiše ga i razoriše; kralja njegova i žitelje okolnih mjesta pobiše oštricom mača. Kletom uništenju izručiše sve njegovo stanovništvo. Ne poštedješe nikoga. I učini Jošua s Debirom i njegovim kraljem kao što je učinio s Hebronom i njegovim kraljem, s Libnom i njezinim kraljem."},{"v":40,"t":"Tako je Jošua zauzeo sav onaj kraj: Gorje i Negeb, Šefelu i Visočje - i sve njihove kraljeve. Ne ostavi preživjelih, već izruči kletom uništenju sve što je disalo, kako je zapovjedio Jahve, Bog Izraelov."},{"v":41,"t":"I pobi ih Jošua sve od Kadeš Barnee do Gaze i sav kraj Gošen do Gibeona."},{"v":42,"t":"Sve tamošnje kraljeve i zemlje njihove zauze Jošua ujedanput, jer se za Izraela borio Jahve, Bog Izraelov."},{"v":43,"t":"Naposljetku se Jošua i sav Izrael vratiše u tabor u Gilgalu."}]},"11":{"hr":[{"v":1,"t":"Kad je sve to čuo Jabin, kralj od Hasora, obavijesti Jobaba, kralja od Madona, i kralja od Šimrona, i kralja od Akšafa,"},{"v":2,"t":"i kraljeve na sjeveru, u Gorju, i u Arabi južno od Kinereta, i u Šefeli, i na uzvišicama Dora prema moru;"},{"v":3,"t":"Kanaance na istoku i zapadu, Amorejce, Hetite, Perižane i Jebusejce u planinama, Hivijce pod Hermonom u zemlji Mispi."},{"v":4,"t":"Svi oni izađu sa svim svojim četama, s mnoštvom što ga bijaše kao pijeska na obali morskoj i s mnogim konjima i kolima."},{"v":5,"t":"Udruže se, dakle, svi ti kraljevi i utabore se zajedno na vodama Meroma da se bore protiv Izraela."},{"v":6,"t":"Tada Jahve reče Jošui: “Ne boj se njih, jer ću sutra u ovo doba učiniti te će svi biti pobijeni pred Izraelom; konje njihove osakati, a bojna im kola ognjem spali.”"},{"v":7,"t":"Jošua povede na njih sve svoje ratnike, iznenada ih napade na vodama Meroma i udari na njih."},{"v":8,"t":"I Jahve ih dade u ruke Izraelcima te ih oni pobiše i protjeraše sve do Velikog Sidona i do Misrefot Majima i do ravnice Mispe na istoku; i poraziše ih tako te nitko ne preživje."},{"v":9,"t":"Jošua učini kako mu je Jahve zapovjedio: konje im osakati, a kola im ognjem spali."},{"v":10,"t":"U to se vrijeme vrati Jošua i zauze Hasor, a njegova kralja pogubi mačem. Hasor je nekoć bio glavni grad svima tim kraljevstvima."},{"v":11,"t":"Pobili su sve oštricom mača, izvršujući “herem”, kletvu. Ne ostade ništa živo, a Hasor spališe ognjem."},{"v":12,"t":"Sve gradove onih kraljeva pokori Jošua i pobi kraljeve oštricom mača, izvršujući “herem”, kletvu, kao što je bio zapovjedio Mojsije, sluga Jahvin."},{"v":13,"t":"Od ostalih gradova koji se dizahu na svojim brežuljcima Izraelci nisu spalili ni jednoga, osim Hasora, koji spali Jošua."},{"v":14,"t":"Sav plijen iz tih gradova i stoku razdijeliše sinovi Izraelovi među sobom, a sve ljude pobiše oštricom mača, istrijebiše ih i ni žive duše ne ostade."},{"v":15,"t":"Sve što Jahve bijaše zapovjedio svome sluzi Mojsiju, zapovjedio je Mojsije Jošui, a Jošua sve izvršio, ne izostavivši ništa od svega što Jahve bijaše zapovjedio Mojsiju."},{"v":16,"t":"Tako je Jošua zauzeo svu zemlju: Gorje, sav Negeb i svu zemlju Gošen, Šefelu, Arabu, Izraelsko gorje i njegove brežuljke,"},{"v":17,"t":"od gore Halaka, koja se diže prema Seiru, pa do Baal Gada, u ravnici libanonskoj pod gorom Hermonom; zarobio je sve njihove kraljeve, pobio ih i pogubio."},{"v":18,"t":"Dugo je vremena ratovao Jošua s tim kraljevima."},{"v":19,"t":"Nije bilo ni jednoga grada koji je sklopio mir s sinovima Izraelovim, osim Hivijaca, koji su živjeli u Gibeonu: sve ih zauzeše ratom."},{"v":20,"t":"Jahve im bijaše otvrdnuo srca te su izašli u boj protiv Izraela i pali pod “herem”, kletvu bez smilovanja, da budu istrijebljeni, kako je to Jahve bio zapovjedio Mojsiju."},{"v":21,"t":"U ono vrijeme dođe Jošua i istrijebi Anakovce iz Gorja, iz Hebrona, iz Debira, iz Anaba, iz svega gorja Judina i iz svega gorja Izraelova: predade ih “heremu”, uništenju, njih i sve njihove gradove."},{"v":22,"t":"Tako ne ostade nijedan Anakovac u svoj zemlji sinova Izraelovih, osim u Gazi, u Gatu i Ašdodu."},{"v":23,"t":"Jošua zauze svu zemlju, kao što je Jahve bio rekao Mojsiju, i dade je u baštinu Izraelu podijelivši je po plemenima. I konačno zemlja počinu od rata."}]},"12":{"hr":[{"v":1,"t":"Ovo su zemaljski kraljevi što su ih pobijedili Izraelci i osvojili njihovu zemlju s onu stranu Jordana k istoku, od potoka Arnona do gore Hermona, sa svom Arabom na istoku:"},{"v":2,"t":"Sihon, kralj amorejski, koji je stolovao u Hešbonu; njegovo se kraljevstvo protezalo od Aroera, koji leži na rubu doline potoka Arnona, sredinom doline i polovinom Gileada pa do potoka Jaboka, gdje je graničilo s Amoncima;"},{"v":3,"t":"i na istoku mu bila Araba do Keneretskog mora s jedne strane i sve do Arabskog ili Slanog mora prema Bet Haješimotu; i dalje na jugu do obronaka Pisge."},{"v":4,"t":"Međašio s njime Og, kralj bašanski, jedan od posljednjih Refaimaca; stolovao je u Aštarotu i Edreju."},{"v":5,"t":"A vladao je gorom Hermonom i Salkom, čitavim Bašanom sve do gešurske i maakadske međe te drugom polovinom Gileada sve do granice Sihona, kralja hešbonskoga."},{"v":6,"t":"Mojsije, sluga Jahvin, i sinovi Izraelovi sve su ih pobili i predao je Mojsije, sluga Jahvin, tu zemlju u posjed plemenu Rubenovu i Gadovu plemenu te polovini plemena Manašeova."},{"v":7,"t":"A ovo su zemaljski kraljevi što su ih pobijedili Jošua i sinovi Izraelovi s ovu stranu Jordana k zapadu, od Baal Gada u libanonskoj ravnici pa do gore Halaka, koja se diže prema Seiru, a tu je zemlju Jošua dao u baštinu plemenima Izraelovim prema njihovim dijelovima,"},{"v":8,"t":"u Gorju, u Šefeli, u Arabi i po obroncima, u Pustinji te u Negebu: zemlju hetitsku, amorejsku i kanaansku, perižansku, hivijsku i jebusejsku:"},{"v":9,"t":"jerihonski kralj, jedan; kralj Aja kod Betela, jedan;"},{"v":10,"t":"jeruzalemski kralj, jedan; hebronski kralj, jedan;"},{"v":11,"t":"jarmutski kralj, jedan; lakiški kralj, jedan;"},{"v":12,"t":"eglonski kralj, jedan; gezerski kralj, jedan;"},{"v":13,"t":"debirski kralj, jedan; gederski kralj, jedan;"},{"v":14,"t":"hormski kralj, jedan; aradski kralj, jedan;"},{"v":15,"t":"kralj Libne, jedan; adulamski kralj, jedan;"},{"v":16,"t":"makedski kralj, jedan; betelski kralj, jedan;"},{"v":17,"t":"kralj Tapuaha, jedan; heferski kralj, jedan;"},{"v":18,"t":"afečki kralj, jedan; šaronski kralj, jedan;"},{"v":19,"t":"madonski kralj, jedan; hasorski kralj, jedan;"},{"v":20,"t":"šimron-meronski kralj, jedan; ahšafski kralj, jedan;"},{"v":21,"t":"tanaački kralj, jedan; megidski kralj, jedan;"},{"v":22,"t":"kedeški kralj, jedan; kralj Jokneama na Karmelu, jedan;"},{"v":23,"t":"dorski kralj u pokrajini dorskoj, jedan; gojski kralj u Gilgalu, jedan;"},{"v":24,"t":"tirški kralj, jedan. U svemu trideset i jedan kralj."}]},"13":{"hr":[{"v":1,"t":"Kad je Jošua ostario i odmakao u svojim godinama, reče mu Jahve: “Već si star i vremešan, a ostalo je mnogo zemlje da se osvoji."},{"v":2,"t":"Evo područja što još preostaju: sve pokrajine filistejske i sva zemlja gešurska;"},{"v":3,"t":"od Šihora, što je pred Egiptom, sve do granice Ekrona na sjeveru, a računa se kao područje Kanaanaca; pet kneževina filistejskih: Gaza, Ašdod, Aškelon, Git i Ekron; zatim Avijci"},{"v":4,"t":"na jugu. Sva zemlja kanaanska od Are koja pripada Sidoncima, pa do Afeka i do međe amorejske;"},{"v":5,"t":"onda zemlja Giblijaca i sav Libanon prema istoku, od Baal Gada u podnožju gore Hermona do Lebo Hamata."},{"v":6,"t":"Sve stanovnike gorja, od Libanona do Misrefota na zapadu - sve Sidonce otjerat ću ispred sinova Izraelovih. Samo razdijeli Izraelu zemlju u baštinu, kao što sam ti zapovjedio."},{"v":7,"t":"Razdijeli, dakle, tu zemlju u baštinu među devet plemena i polovinu plemena Manašeova.”"},{"v":8,"t":"Druga polovina plemena Manašeova, a s njome pleme Rubenovo i Gadovo, primiše svoju baštinu koju im je predao Mojsije preko Jordana, na istoku. Mojsije, sluga Jahvin, dodijelio im je ovako:"},{"v":9,"t":"od Aroera, koji se nalazi uz obalu potoka Arnona, i od grada usred doline, svu visoravan od Medebe do Dibona;"},{"v":10,"t":"sve gradove Sihona, kralja amorejskoga, koji je vladao u Hešbonu, sve do međe sinova Amonovih;"},{"v":11,"t":"i Gilead, i krajinu gešursku i maakansku sa svom gorom Hermonom, i sav Bašan do Salke;"},{"v":12,"t":"a u Bašanu sve kraljevstvo Oga, koji je vladao u Aštarotu i Edreju i bio posljednji potomak Refaima. Mojsije ih je pobijedio i protjerao."},{"v":13,"t":"Ali sinovi Izraelovi nisu protjerali Gešurce i Maakance, pa tako ostadoše Gešurci i Maakanci usred Izraela sve do današnjega dana."},{"v":14,"t":"Samo plemenu Levijevu ne dade baštine: Jahve, Bog Izraelov, njegova je baština, kao što je rekao."},{"v":15,"t":"Mojsije dade plemenu sinova Rubenovih dijelove po njihovim porodicama."},{"v":16,"t":"Primili su zemlju od Aroera, koji leži uz obalu potoka Arnona, i od grada koji je u sredini doline i svu visoravan kod Medebe;"},{"v":17,"t":"Hešbon sa svim njegovim gradovima koji leže na visoravni: Dibon, Bamot Baal, Bet Baal Meon;"},{"v":18,"t":"Jahas, Kedemot, Mefaat;"},{"v":19,"t":"Kirjatajim, Sibmu i Seret Hašahar na gori iznad doline;"},{"v":20,"t":"Bet Peor, Ašdot Hapisgu, Bet Haješimot;"},{"v":21,"t":"sve gradove na visoravni i sve kraljevstvo Sihona, amorejskog kralja, koji je vladao u Hešbonu. Mojsije ga je pobijedio kao i knezove midjanske: Avija, Rekema, Sura, Hura, Reba, podanike Sihonove, koji su živjeli u toj zemlji;"},{"v":22,"t":"i vrača Bileama, sina Beorova, ubili su sinovi Izraelovi oštricom mača s ostalim žrtvama."},{"v":23,"t":"Međa sinova Rubenovih bijaše Jordan. To je bila baština sinova Rubenovih po njihovim porodicama: gradovi i sela njihova."},{"v":24,"t":"Onda dade Mojsije plemenu Gadovu, sinovima Gadovim, dijelove po porodicama njihovim."},{"v":25,"t":"Primili su u posjed: Jazer i sve gradove gileadske, polovinu zemlje sinova Amonovih sve do Aroera, nasuprot Rabi,"},{"v":26,"t":"i od Hešbona do Ramat Hamispe i Betonima, i od Mahanajima do pokrajine Lo-Debar;"},{"v":27,"t":"a u dolini: Bet Haram, Bet Nimru, Sukot i Safon, to jest ostatak kraljevstva Sihona, kralja hešbonskoga; Jordan s obalom sve do kraja Kineretskoga mora, na istočnoj strani Jordana."},{"v":28,"t":"To je baština sinova Gadovih, po njihovim porodicama, gradovi i sela njihova."},{"v":29,"t":"Mojsije je dao dio polovini plemena Manašeova po njegovim porodicama."},{"v":30,"t":"Dobili su u posjed zemlju od Mahanajima, sav Bašan, sve kraljevstvo Oga, kralja bašanskoga, i sva Sela Jairova što su u Bašanu - šezdeset gradova."},{"v":31,"t":"A polovina Gileada, Aštarot i Edrej, gradovi kraljevstva Ogova u Bašanu, pripali su sinovima Makira, sina Manašeova, i to polovini sinova Makirovih po njihovim porodicama."},{"v":32,"t":"Tako je Mojsije bio podijelio baštine na Moapskim poljanama, s druge strane Jordana, istočno od Jerihona."},{"v":33,"t":"Levijevu plemenu ne dade Mojsije baštine: Jahve, Bog Izraelov, njihova je baština, kao što im je sam rekao."}]},"14":{"hr":[{"v":1,"t":"Ovo je što su dobili u baštinu sinovi Izraelovi u zemlji kanaanskoj - što su im razdijelili u baštinu svećenik Eleazar i Jošua, sin Nunov, i glavari porodica izraelskih plemena."},{"v":2,"t":"Ždrijebom su razdijelili baštinu, kao što je Jahve odredio preko Mojsija, među devet plemena i polovinu desetoga plemena."},{"v":3,"t":"Mojsije je odredio baštinu dvama plemenima i polovini desetog plemena s onu stranu Jordana, a levitima nije dao baštine među njima."},{"v":4,"t":"Jer bijahu dva plemena sinova Josipovih: Manašeovo i Efrajimovo. A levitima nisu dali dijela u zemlji nego gradove za prebivanje i pašnjake za njihovu stoku i za blago njihovo."},{"v":5,"t":"Kako je Jahve zapovjedio Mojsiju, tako su učinili sinovi Izraelovi pri diobi zemlje."},{"v":6,"t":"Sinovi Judini pristupe k Jošui u Gilgalu, a Kaleb, sin Jefuneov, Kenižanin, reče mu: “Ti znaš što je Jahve rekao Mojsiju, čovjeku Božjem, za mene i za tebe u Kadeš Barnei."},{"v":7,"t":"Bilo mi je četrdeset godina kad me posla Mojsije, sluga Jahvin, iz Kadeš Barnee da uhodim zemlju. I donio sam mu izvješće kako sam najbolje znao."},{"v":8,"t":"Braća koja su pošla sa mnom uplašila su srce naroda, ali sam ja vršio volju Jahve, Boga svojega."},{"v":9,"t":"I onoga se dana zakle Mojsije: 'Zemlja kojom je stupala noga tvoja pripast će tebi i sinovima tvojim u vječnu baštinu, jer si vršio volju Jahve, Boga mojega.'"},{"v":10,"t":"I vidiš, Jahve me sačuvao u životu, kao što je rekao. Već je prošlo četrdeset i pet godina kako je Jahve to obećao Mojsiju, dok je Izrael još išao pustinjom; sada mi je osamdeset i pet godina,"},{"v":11,"t":"ali sam još i danas snažan kao što sam bio onoga dana kad me Mojsije poslao kao uhodu. Kao nekoć, i sada je moja snaga u meni, za borbu, da odem i da se vratim."},{"v":12,"t":"Daj mi sada ovo gorje, koje mi je Jahve obećao onoga dana. Sam si čuo onoga dana. Ondje su Anakovci, a i gradovi su im veliki i tvrdi. Ako je Jahve sa mnom, protjerat ću ih, kako je to obećao Jahve.”"},{"v":13,"t":"Tada ga Jošua blagoslovi i dade Kalebu, sinu Jefuneovu, Hebron u baštinu."},{"v":14,"t":"Hebron je pripao u baštinu Kalebu, sinu Jefuneovu, Kenižaninu, sve do danas, jer je Kaleb vršio volju Jahve, Boga Izraelova."},{"v":15,"t":"Hebron se prije zvao Kirjat Arba; a Arba bijaše velik čovjek među Anakovcima. I počinu zemlja od rata."}]},"15":{"hr":[{"v":1,"t":"Dio što je pripao plemenu sinova Judinih, po njihovim porodicama, bijaše prema granici edomskoj, na jug do Sinske pustinje, na krajnjem jugu."},{"v":2,"t":"A južna im međa išla od kraja Slanoga mora od zaljeva što je na jugu;"},{"v":3,"t":"izlazila je onda južno od Akrabimskog uspona, pružala se preko Sina i uzlazila južno od Kadeš Barnee, prelazila Hesron, penjala se k Adari i odatle okretala prema Karkai,"},{"v":4,"t":"potom prelazila Asmon i dopirala do Potoka egipatskog i najposlije izbijala na more. To vam je južna međa."},{"v":5,"t":"Na istoku je međa bila: Slano more do ušća Jordana. Sjeverna je međa počinjala od Slanog mora kod ušća Jordana."},{"v":6,"t":"Odatle je međa uzlazila u Bet-Hoglu, tekla sjeverno uz Bet-Arabu, išla gore na Kamen Bohana, sina Rubenova."},{"v":7,"t":"Međa se zatim dizala od Akorske doline prema Debiru, okretala na sjever prema Gelilotu, koji leži naprama Adumimskom usponu, južno od Potoka; dalje je međa prolazila prema vodama En-Šemeša te izlazila kod En-Rogela."},{"v":8,"t":"Odatle se preko doline Ben-Hinom s juga dizala k Jebusejskom obronku, to jest k Jeruzalemu. Potom se uspinjala na vrh gore koja prema zapadu gleda na dolinu Hinon i leži na sjevernom kraju doline Refaima."},{"v":9,"t":"S vrha te gore zavijala je međa na izvor Neftoah te izlazila prema gradovima u gori Efronu da zatim okrene k Baali, to jest Kirjat Jearimu."},{"v":10,"t":"Od Baale međa je okretala na zapad prema gori Seiru i onda, prolazeći sjeverno od gore Jearima, to jest Kesalona, spuštala se u Bet-Šemeš te išla k Timni."},{"v":11,"t":"Dalje je međa tekla k sjevernom obronku Ekrona, okretala prema Šikronu, prelazila visove Baale, pružala se do Jabneela da konačno izbije na more."},{"v":12,"t":"Zapadna je međa Veliko more s obalom. To su bile zemlje sinova Judinih, unaokolo, po porodicama njihovim."},{"v":13,"t":"Kaleb, sin Jefuneov, primi dio među sinovima Judinim, kako je Jahve naredio Jošui. Dao mu je Kirjat Arbu, glavni grad sinova Anakovih - Hebron."},{"v":14,"t":"Kaleb protjera odatle tri sina Anakova: Šešaja, Ahimana i Talmaja, potomke Anakove."},{"v":15,"t":"Odatle krenu na stanovnike Debira, koji se nekoć zvao Kirjat Sefer."},{"v":16,"t":"Tada reče Kaleb: “Tko pokori i zauzme Kirjat Sefer, dat ću mu svoju kćer Aksu za ženu.”"},{"v":17,"t":"Zauze ga Otniel, sin Kenaza, brata Kalebova; i dade mu Kaleb svoju kćer Aksu za ženu."},{"v":18,"t":"Kad je prišla mužu, on je nagovori da u svoga oca zatraži polje. Ona siđe s magarca, a Kaleb je upita: “Šta hoćeš?”"},{"v":19,"t":"Ona odgovori: “Daj mi blagoslov! Kad si mi dao kraj u Negebu, daj mi i koji izvor vode.” I on joj dade Gornje i Donje izvore."},{"v":20,"t":"To je bila baština plemena sinova Judinih po porodicama njihovim."},{"v":21,"t":"Međašni su gradovi plemena sinova Judinih, duž edomske međe prema jugu, bili: Kabseel, Eder, Jagur;"},{"v":22,"t":"Kina, Dimona, Adada;"},{"v":23,"t":"Kedeš, Hasor Jitnan;"},{"v":24,"t":"Zif, Telem, Bealot;"},{"v":25,"t":"Novi Hasor, Kirjat Hesron (to jest Hasor);"},{"v":26,"t":"Amam, Šema, Molada;"},{"v":27,"t":"Hasar Gada, Hešmon, Bet-Pelet;"},{"v":28,"t":"Hasar Šual, Beer Šeba s pripadnim područjima;"},{"v":29,"t":"Baala, Ijim, Esem;"},{"v":30,"t":"Eltolad, Kesil, Horma;"},{"v":31,"t":"Siklag, Madmana, Sansana;"},{"v":32,"t":"Lebaot, Šelhim, En Rimon: svega dvadeset i devet gradova s njihovim selima."},{"v":33,"t":"U Dolini: Eštaol, Sora, Ašna;"},{"v":34,"t":"Zanoah, En Ganim, Tapuah, Haenam;"},{"v":35,"t":"Jarmut, Adulam, Soko, Azeka;"},{"v":36,"t":"Šaarajim, Aditajim, Hagedera i Gederotajim: četrnaest gradova s njihovim selima."},{"v":37,"t":"Senan, Hadaša, Migdal-Gad;"},{"v":38,"t":"Dilean, Hamispe, Jokteel;"},{"v":39,"t":"Lakiš, Boskat, Eglon;"},{"v":40,"t":"Kabon, Lahmas, Kitliš;"},{"v":41,"t":"Gederot, Bet-Dagon, Naama, Makeda: šesnaest gradova s njihovim selima."},{"v":42,"t":"Libna, Eter, Ašan;"},{"v":43,"t":"Jiftah, Ašna, Nesib;"},{"v":44,"t":"Keila, Akzib i Mareša: devet gradova s njihovim selima."},{"v":45,"t":"Ekron s naseljima i selima njegovim;"},{"v":46,"t":"od Ekrona pa do Mora, sve što se nalazi pokraj Ašdoda, s njihovim selima;"},{"v":47,"t":"Ašdod s naseljima i selima njegovim, Gaza s naseljima i selima njegovim do Egipatskog potoka i Velikog mora, koje je međa."},{"v":48,"t":"A u Gori: Šamir, Jatir, Soko;"},{"v":49,"t":"Dana, Kirjat Sefer (to je Debir);"},{"v":50,"t":"Anab, Eštemoa, Anim;"},{"v":51,"t":"Gošen, Holon, Gilo: jedanaest gradova s njihovim selima."},{"v":52,"t":"Arab, Duma, Ešean;"},{"v":53,"t":"Janum, Bet-Tapuah, Afeka,"},{"v":54,"t":"Humta, Kirjat Arba (to jest Hebron), Sior: devet gradova s njihovim selima."},{"v":55,"t":"Maon, Karmel, Zif, Juta;"},{"v":56,"t":"Jizreel, Jokdeam, Zanoah;"},{"v":57,"t":"Hakajin, Gibea, Timna: deset gradova s njihovim selima."},{"v":58,"t":"Halhul, Bet-Sur, Gedor;"},{"v":59,"t":"Maarat, Bet-Anot, Eltekon: šest gradova s njihovim selima. Tekoa, Efrata (to jest Betlehem), Peor, Etan, Kulon, Tatam, Sores, Karem, Galim, Beter, Manah: jedanaest gradova s njihovim selima."},{"v":60,"t":"Kirjat Baal (to jest Kirjat Jearim) i Haraba: dva grada s njihovim selima."},{"v":61,"t":"U pustinji: Bet Haaraba, Midin, Sekaka;"},{"v":62,"t":"Hanibšan, Slani grad i En-Gedi: šest gradova s njihovim selima."},{"v":63,"t":"A Jebusejce koji su živjeli u Jeruzalemu nisu mogli protjerati sinovi Judini. Tako su ostali sa sinovima Judinim u Jeruzalemu sve do danas."}]},"16":{"hr":[{"v":1,"t":"Sinovima Josipovim pripao je ždrijebom posjed: od Jordana kod Jerihona, od Jerihonskih voda na istok, pa pustinjom k Betelskoj gori;"},{"v":2,"t":"od Betel-Luza međa se nastavljala područjem Arkijaca do Atarota."},{"v":3,"t":"Potom se spuštala na zapad do jafletske međe, sve do Donjeg Bet-Horona i do Gezera, odakle je izlazila na more."},{"v":4,"t":"To je bila baština Josipovih sinova: Manašea i Efrajima."},{"v":5,"t":"Područje sinova Efrajimovih po njihovim porodicama bilo je ovo: međa baštine njihove prema istoku išla je od Atrot Adara pa do Gornjega Bet-Horona."},{"v":6,"t":"Odatle se pružala do mora ... (išla na) Mikmetat na sjeveru i zavijala dalje na istok prema Taanat Šilu i prolazila s istočne strane do Janoaha."},{"v":7,"t":"Od Janoaha spuštala se u Atarot i Naarat i onda, dotičući se Jerihona, udarala na Jordan."},{"v":8,"t":"Od Tapuaha išla je ta međa prema zapadu do potoka Kane te izbijala na more. To je bila baština plemena sinova Efrajimovih po njihovim porodicama."},{"v":9,"t":"A Efrajimovi su sinovi imali sve te gradove s njihovim selima i još odvojene gradove usred baštine sinova Manašeovih."},{"v":10,"t":"Ali nisu uspjeli otjerati Kanaanaca koji su živjeli u Gezeru. Tako su Kanaanci ostali među sinovima Efrajimovim do danas, ali im bijaše nametnuta tlaka."}]},"17":{"hr":[{"v":1,"t":"Ždrijebom je dopao i dio plemenu Manašeovu, jer je Manaše bio prvenac Josipov. Makiru, prvencu Manašeovu, ocu Gileadovu - bijaše on ratnik bez premca - pripade Gilead i Bašan."},{"v":2,"t":"Dobili su svoj dio i ostali sinovi Manašeovi po svojim porodicama: sinovi Abiezerovi, sinovi Helekovi, sinovi Asrielovi; sinovi Šekemovi, sinovi Heferovi i sinovi Šemidini. To su muški potomci Manašea, sina Josipova, po svojim porodicama."},{"v":3,"t":"A Selofhad, sin Hefera, sina Gileada, sina Makira, sina Manašeova, nije imao sinova nego samo kćeri. Evo im imena: Mahla, Noa, Hogla, Milka i Tirsa."},{"v":4,"t":"One dođoše pred svećenika Eleazara i pred Jošuu, sina Nunova, i pred glavare govoreći: “Jahve je zapovjedio Mojsiju da se i nama dade baština među našom braćom.” I dadoše im po Jahvinoj zapovijedi baštinu među braćom njihova oca."},{"v":5,"t":"Tako je dopalo Manašeu deset dijelova, povrh gileadske i bašanske zemlje, koje su s onu stranu Jordana."},{"v":6,"t":"Kćeri Manašeove dobiše baštinu među njegovim sinovima, a zemlja gileadska pripala je drugim sinovima Manašeovim."},{"v":7,"t":"Međa je Manašeova išla od Ašera do Mikmetata, koji leži nasuprot Šekemu, a zatim zavijala desno prema Jašibu na izvoru Tapuahu."},{"v":8,"t":"Pokrajina Tapuah pripadaše Manašeu, ali sam Tapuah na međi Manašeovoj pripadaše sinovima Efrajimovim."},{"v":9,"t":"Međa je silazila do potoka Kane. Južno od potoka bili su i ovi gradovi što su Efrajimovim sinovima pripadali između Manašeovih gradova; a zemlja se Manašeova nalazila na sjeveru i izbijala na more."},{"v":10,"t":"Područje s juga pripadalo je Efrajimu, na sjeveru Manašeu, a more im bi međa; na sjeveru su graničili s Ašerom, a s Jisakarom na istoku."},{"v":11,"t":"Manašeu pripadahu u Jisakaru i Ašeru: Bet-Šean sa svojim selima, Jibleam sa svojim selima, stanovnici Dora sa svojim selima, stanovnici En-Dora sa svojim selima, stanovnici Taanaka sa svojim selima, stanovnici Megida sa svojim selima; dakle: tri područja."},{"v":12,"t":"Ali Manašeovi sinovi nisu mogli osvojiti te gradove i zato su Kanaanci ostali u tom kraju."},{"v":13,"t":"Ali kad su ojačali sinovi Izraelovi, nametnuše Kanaancima tlaku, ali ih nisu uspjeli protjerati."},{"v":14,"t":"Obrate se tada Josipovi sinovi Jošui i upitaju: “Zašto si nam dao u baštinu prema jednom ždrijebu, samo jedan dio, kad smo mnogobrojni i Jahve nas dosad blagoslivljao?”"},{"v":15,"t":"Jošua im odgovori: “Kad ste narod mnogobrojan, pođite u šumu i krčite ondje sebi zemlje u periškoj i refaimskoj krajini, ako vam je pretijesna gora Efrajimova.”"},{"v":16,"t":"A sinovi Josipovi rekoše: “Gora nam ova neće biti dosta, a svi Kanaanci koji žive u ravnici imaju željezna kola, oni što su u Bet-Šeanu i selima njegovim i oni koji su u dolini jizreelskoj.”"},{"v":17,"t":"Tada odgovori Jošua domu Josipovu, i Efrajimu i Manašeu: “Vi ste brojan narod i imate silnu snagu. Zato nećeš dobiti samo jedan ždrijeb:"},{"v":18,"t":"neka gora bude tvoja. Ako je šumovita, iskrči je pa će obronci biti posjed doma tvoga. Istjerat ćeš sigurno Kanaance ako i imaju željezna kola, ako i jesu jaki.”"}]},"18":{"hr":[{"v":1,"t":"Sabrala se zajednica sinova Izraelovih u Šilo, i ondje razapeše Šator sastanka. Sva im se zemlja pokorila."},{"v":2,"t":"Ali ostade među sinovima Izraelovim još sedam plemena koja nisu primila svoje baštine."},{"v":3,"t":"Tada im reče Jošua: “Dokle ćete oklijevati da pođete i zaposjednete zemlju koju vam je dao Jahve, Bog vaših otaca?"},{"v":4,"t":"Izaberite po tri čovjeka iz svakoga plemena, a ja ću ih poslati da popišu svu zemlju za diobu. Kad se vrate k meni,"},{"v":5,"t":"razdijelit ću zemlju na sedam dijelova. Neka Juda ostane na svome području na jugu, a Josipov dom neka ostane u svome kraju na sjeveru."},{"v":6,"t":"A vi raspišite zemlju na sedam dijelova i donesite mi amo da bacim ždrijeb za vas ovdje pred Jahvom, Bogom našim."},{"v":7,"t":"Leviti neće imati dijela među vama jer je svećeništvo Jahvino njihova baština; a Gad, Ruben i polovina plemena Manašeova primili su svoju baštinu na istočnoj strani Jordana - onu koju im je dao Mojsije, sluga Jahvin.”"},{"v":8,"t":"Spreme se ti ljudi na put, a Jošua zapovjedi onima koji su pošli popisati zemlju: “Idite i obiđite svu zemlju i opišite je, pa se onda vratite k meni da bacim ždrijeb ovdje pred Jahvom u Šilu.”"},{"v":9,"t":"Odoše oni ljudi, prođoše zemljom i u knjigu popisaše sve gradove u sedam dijelova, pa se vratiše k Jošui u tabor u Šilu."},{"v":10,"t":"A Jošua baci za njih ždrijeb u Šilu pred Jahvom i ondje razdijeli Jošua zemlju sinovima Izraelovim po njihovim dijelovima plemenskim."},{"v":11,"t":"I pade ždrijeb na pleme sinova Benjaminovih po njihovim porodicama: utvrdi se da je njihov dio između dijela sinova Judinih i sinova Josipovih."},{"v":12,"t":"Sjeverna im se međa protezala od Jordana te išla uza sjeverni obronak Jerihona, uspinjala se sa zapada na goru i završavala se u pustinji Bet-Avenu."},{"v":13,"t":"Odatle je išla k Luzu, k južnom obronku Luza, to jest Betela; spuštala se zatim u Atrot-Adar, kraj brda koje je južno od Donjeg Bet-Horona."},{"v":14,"t":"Međa se dalje savijala i okretala sa zapada prema jugu, od gore koja se diže nasuprot Bet-Horonu s juga, i svršavala se kod Kirjat Baala, danas Kirjat Jearima, grada sinova Judinih. To je zapadna strana."},{"v":15,"t":"Južna se strana počinjala od granice Kirjat Jearima, pa se pružala na zapad k vrelu Neftoahu;"},{"v":16,"t":"potom se spuštala međa do kraja gore koja je prema dolini Ben-Hinomu, na sjeveru refaimske nizine, silazila zatim u dolinu Hinom uz Jebusejski obronak i dosegla do izvora Rogela."},{"v":17,"t":"Zatim se savijala od sjevera te izlazila na En-Šemeš i doticala Gelilot, koji se diže prema Adumimskom usponu, i silazila na Kamen Bohana, sina Rubenova."},{"v":18,"t":"Prolazila je zatim obronkom sa sjeverne strane prema Bet-Haarabi i silazila do Arabe."},{"v":19,"t":"Dalje je tekla međa uz obronak Bet-Hogle prema sjeveru i svršavala se na sjevernom Jeziku Slanog mora, do južnog kraja Jordana. To je južna međa."},{"v":20,"t":"Jordan je pak bio međa s istočne strane. To je baština sinova Benjaminovih, s njihovim međama unaokolo po porodicama njihovim."},{"v":21,"t":"Gradovi plemena sinova Benjaminovih po porodicama njihovim jesu: Jerihon, Bet-Hogla, Emek Kesis;"},{"v":22,"t":"Bet-Haaraba, Samarajim, Betel;"},{"v":23,"t":"Avim, Para, Ofra;"},{"v":24,"t":"Kefar Haamona, Ofni i Gaba: dvanaest gradova s njihovim selima."},{"v":25,"t":"Gibeon, Rama, Beerot;"},{"v":26,"t":"Mispe, Kefira i Mosa;"},{"v":27,"t":"Rekem, Jirpeel, Tarala;"},{"v":28,"t":"Sela Haelef, Jebus (to je Jeruzalem), Gibat i Kirjat: četrnaest gradova s njihovim selima. To je baština sinova Benjaminovih po porodicama njihovim."}]},"19":{"hr":[{"v":1,"t":"Drugi ždrijeb izađe za Šimuna, za pleme sinova Šimunovih po porodicama njihovim: njihova je baština bila usred sinova Judinih."},{"v":2,"t":"Dodijeljena im je kao baština: Beer Šeba, Šeba, Molada;"},{"v":3,"t":"Hasar Šual, Bala, Esem;"},{"v":4,"t":"Eltolad, Betul, Horma,"},{"v":5,"t":"Siklag, Bet-Hamarkabot, Hasar Susa,"},{"v":6,"t":"Bet-Lebaot i Šaruhen: trinaest gradova i njihova sela."},{"v":7,"t":"Ajin, Rimon, Eter i Ašan: četiri grada s njihovim selima."},{"v":8,"t":"I sva naselja što su oko tih gradova, do Baalat Beera, Ramat Negeba. To je baština plemena sinova Šimunovih po porodicama njihovim."},{"v":9,"t":"Baština je sinova Šimunovih bila od dijela sinova Judinih, jer dio dodijeljen sinovima Judinim bijaše za njih prevelik. Zato su sinovi Šimunovi dobili svoju baštinu usred njihova područja."},{"v":10,"t":"Treći ždrijeb izađe za sinove Zebulunove po porodicama njihovim: njihovo je područje sezalo do Sarida,"},{"v":11,"t":"odakle im se međa na zapadu penjala do Marale, doticala Dabešet i dopirala do potoka koji je nasuprot Jokneamu."},{"v":12,"t":"Od Sarida je međa okretala prema istoku, sve do međe Kislot Tabora, odakle je izlazila do Dabrata i uspinjala se do Jafije."},{"v":13,"t":"A odatle je išla opet prema istoku, na Git Hefer i na Ita Kasin, izlazila na Rimon i vraćala se do Nee."},{"v":14,"t":"Onda je okretala sa sjevera oko Hanatona i završavala se u dolini Jiftah-Elu."},{"v":15,"t":"Pa Katat, Nahalal, Šimron, Jidalu i Betlehem: dvanaest gradova s njihovim selima."},{"v":16,"t":"To je bila baština sinova Zebulunovih po porodicama njihovim: ti gradovi s njihovim selima."},{"v":17,"t":"Četvrti je ždrijeb izašao za Jisakara, za sinove Jisakarove po njihovim porodicama."},{"v":18,"t":"A posjed im je bio: Jizreel, Hakesulot, Šunem;"},{"v":19,"t":"Hafarajim, Šion, Anaharat;"},{"v":20,"t":"Harabit, Kišjon, Ebes;"},{"v":21,"t":"Remet i En-Ganim, En-Hada i Bet-Pases."},{"v":22,"t":"Potom međa dotiče Tabor, Šahasimu i Bet-Šemeš i izlazi na Jordan: šesnaest gradova s njihovim selima."},{"v":23,"t":"To je baština plemena sinova Jisakarovih po porodicama njihovim: ti gradovi s njihovim selima."},{"v":24,"t":"Peti ždrijeb iziđe za pleme sinova Ašerovih po njihovim porodicama."},{"v":25,"t":"Njihova je zemlja bila: Helkat, Hali, Beten, Akšaf,"},{"v":26,"t":"Alamelek, Amad, Mišal. Na zapadu je međa doticala Karmel i Šihor Libnat."},{"v":27,"t":"Zatim je okretala prema sunčanom istoku do Bet-Dagona i doticala se Zebuluna i doline Jiftahela sa sjevera; protezala se dalje Bet-Haemekom i Neielom i dosezala slijeva Kabul,"},{"v":28,"t":"pa Abdon, Rehob, Hamon i Kanu sve do Velikog Sidona."},{"v":29,"t":"Međa je tada zavijala prema Rami i do tvrdoga grada Tira te je okretala prema Hosi i izlazila na more. Obuhvaćala je Mehaleb, Akzib,"},{"v":30,"t":"Ako, Afek i Rehob: dvadeset i dva grada s njihovim selima."},{"v":31,"t":"To je baština plemena sinova Ašerovih po porodicama njihovim: ti gradovi i njihova sela."},{"v":32,"t":"Šesti ždrijeb izađe za sinove Naftalijeve po njihovim porodicama."},{"v":33,"t":"Njihova međa ide od Helefa i od Hrasta u Saananimu, od Adami Hanekeba i Jabneela do Lakuma i izbija na Jordan."},{"v":34,"t":"Potom međa okreće na zapad k Aznot Taboru i pruža se odande prema Hukoku; na jugu se dotiče Zebuluna, na zapadu Ašera, na istoku Jordana."},{"v":35,"t":"Utvrđeni gradovi bijahu Hasidim, Ser, Hamat, Rakat, Kineret;"},{"v":36,"t":"Adama, Rama, Hasor,"},{"v":37,"t":"Kedeš, Edrej, En-Hasor;"},{"v":38,"t":"Jiron, Migdal-El, Horem, Bet-Anat, Bet-Šemeš: devetnaest gradova s njihovim selima."},{"v":39,"t":"To je baština plemena Naftalijevih sinova po porodicama njihovim: ti gradovi i njihova sela."},{"v":40,"t":"Izađe sedmi ždrijeb za pleme sinova Danovih po porodicama njihovim."},{"v":41,"t":"Područje baštine njihove bilo je: Sora, Eštaol, Ir Šemeš,"},{"v":42,"t":"Šaalabin, Ajalon, Jitla,"},{"v":43,"t":"Elon, Timna, Ekron,"},{"v":44,"t":"Elteke, Gibeton, Baalat,"},{"v":45,"t":"Jehud, Bene-Berak, Gat-Rimon,"},{"v":46,"t":"Me-Hajarkon i Harakon s područjem prema Jafi."},{"v":47,"t":"Ali područje sinova Danovih bilo je za njih pretijesno; zato udare Danovi sinovi na Lešem, osvoje ga i sve pobiju oštricom mača; zaposjednu grad, nastane se u njemu i Lešem prozovu Dan, po imenu Dana, oca svoga."},{"v":48,"t":"To je baština plemena sinova Danovih po porodicama njihovim: ti im gradovi i sela njihova."},{"v":49,"t":"Kada završe diobu zemlje ždrijebom i utvrde njezine međe, dadu Izraelci Jošui, sinu Nunovu, baštinu u svojoj sredini."},{"v":50,"t":"Po zapovijedi Jahvinoj dali su mu grad koji je sebi želio: Timnat-Serah u Efrajimovoj gori; on utvrdi taj grad i nastani se u njemu."},{"v":51,"t":"To su baštine koje su svećenik Eleazar i Jošua, sin Nunov, i glavari izraelskih plemena podijelili ždrijebom među plemena izraelska u Šilu, pred Jahvom, na vratima Šatora sastanka. Tako je zavšena razdioba zemlje."}]},"20":{"hr":[{"v":1,"t":"Jahve reče Jošui:"},{"v":2,"t":"“Kaži sinovima Izraelovim i reci im: 'Odredite sebi gradove-utočišta za koje sam vam govorio preko Mojsija,"},{"v":3,"t":"da bi onamo mogao pobjeći ubojica koji nehotice ubije koga i da vam budu utočišta od krvnoga osvetnika."},{"v":4,"t":"Ako ubojica utekne u koji od tih gradova, neka stane pred gradska vrata i neka starješinama toga grada iznese svoju stvar. Oni neka ga prime u svoj grad i odrede mu mjesto gdje će prebivati među njima."},{"v":5,"t":"Ako ga krvni osvetnik progoni, ne smiju izručiti ubojicu u njegove ruke: tÓa nehotice je ubio svoga bližnjega, a ne iz mržnje."},{"v":6,"t":"Ubojica neka ostane u tom gradu sve dok ne stupi pred sud zajednice ili do smrti velikoga svećenika koji bude u ono vrijeme. Tada neka se ubojica vrati i neka ode u svoj grad i svome domu - u grad iz kojega je utekao.'”"},{"v":7,"t":"I posvete Kedeš u Galileji, u Naftalijevoj gori; Šekem u Efrajimovoj gori; Kirjat-Arbu, to jest Hebron, u Judinoj gori."},{"v":8,"t":"S druge strane Jordana, istočno od Jerihona, odrede Beser u pustinji, u ravnici plemena Rubenova, i Ramot u Gileadu od plemena Gadova, i Golan u Bašanu od plemena Manašeova."},{"v":9,"t":"To su bili gradovi određeni svim Izraelcima i došljacima koji borave među njima: ovamo je mogao uteći svaki koji nehotice drugoga ubije, a da sam ne pogine od osvetničke ruke dok ne izađe na sud, pred zajednicu."}]},"21":{"hr":[{"v":1,"t":"Pođoše tada glavari levitskih obitelji k svećeniku Eleazaru i Jošui, sinu Nunovu, i plemenskim glavarima Izraela."},{"v":2,"t":"I rekoše im u Šilu, u zemlji kanaanskoj: “Jahve je zapovjedio preko Mojsija da nam se dadu gradovi gdje ćemo živjeti i pašnjaci oko njih za našu stoku.”"},{"v":3,"t":"Izraelci dadoše levitima od svoje baštine, po zapovijedi Jahvinoj, ove gradove s njihovim pašnjacima."},{"v":4,"t":"Iziđe, dakle, ždrijeb za porodice Kehatove: levitima, potomcima svećenika Arona, pripade trinaest gradova od plemena Judina, Šimunova i Benjaminova;"},{"v":5,"t":"ostalim sinovima Kehatovim pripalo je ždrijebom po porodicama deset gradova od plemena Efrajimova i Danova i od polovine plemena Manašeova."},{"v":6,"t":"Sinovi Geršonovi dobiše po porodicama trinaest gradova od plemena Jisakarova, Ašerova i Naftalijeva i od polovine plemena Manašeova u Bašanu."},{"v":7,"t":"Merarijevim sinovima po njihovim porodicama pripalo je dvanaest gradova od plemena Rubenova, Gadova i Zebulunova."},{"v":8,"t":"Tako Izraelci ždrijebom dodijeliše levitima te gradove s pašnjacima, kako bijaše zapovjedio Jahve preko Mojsija."},{"v":9,"t":"Od plemena sinova Judinih i od plemena sinova Šimunovih dodijeljeni su bili ovi gradovi koji se poimence navode:"},{"v":10,"t":"sinovima Aronovim u levitskim porodicama Kehatovim, jer je prvi ždrijeb bio za njih,"},{"v":11,"t":"pripade Kirjat-Arba, glavni grad Anakovaca, to jest Hebron, u Judinoj gori, s pašnjacima unaokolo."},{"v":12,"t":"Ali polja oko toga grada sa selima unaokolo bila su već dana u baštinu Kalebu, sinu Jefuneovu."},{"v":13,"t":"Sinovima svećenika Arona pripade grad-utočište Hebron s pašnjacima i Libna s pašnjacima;"},{"v":14,"t":"Jatir s pašnjacima, Eštemoa s pašnjacima,"},{"v":15,"t":"Holon s pašnjacima, Debir s pašnjacima,"},{"v":16,"t":"Ašan s pašnjacima, Juta s pašnjacima, Bet-Šemeš s pašnjacima. Dakle, devet gradova od ona dva plemena."},{"v":17,"t":"Od plemena Benjaminova: Gibeon s pašnjacima, Geba s pašnjacima,"},{"v":18,"t":"Anatot s pašnjacima, Almon s pašnjacima. Dakle, četiri grada."},{"v":19,"t":"Tako su svećenici, sinovi Aronovi, dobili svega trinaest gradova s njihovim pašnjacima."},{"v":20,"t":"Ostalim levitima u porodicama sinova Kehatovih ždrijebom su pripali gradovi plemena Efrajimova."},{"v":21,"t":"Dali su im grad-utočište Šekem s pašnjacima njegovim na Efrajimovoj gori, zatim Gezer s pašnjacima,"},{"v":22,"t":"Kibsajim s pašnjacima, Bet-Horon s pašnjacima. Dakle, četiri grada."},{"v":23,"t":"Od plemena Danova dobili su: Elteku s pašnjacima i Gibeton s pašnjacima,"},{"v":24,"t":"Ajalon s pašnjacima i Gat-Rimon s pašnjacima. Dakle, četiri grada."},{"v":25,"t":"Od polovine plemena Manašeova: Tanak s pašnjacima i Jibleam s pašnjacima. Dakle, dva grada."},{"v":26,"t":"U svemu: deset su gradova s pašnjacima dobile porodice ostalih sinova Kehatovih."},{"v":27,"t":"Geršonovim sinovima, porodicama levitskim, dadoše od polovine plemena Manašeova grad-utočište Golan u Bašanu i Aštarot s njihovim pašnjacima. Dakle, dva grada."},{"v":28,"t":"Od plemena Jisakarova: Kišon s pašnjacima, Dabrat s pašnjacima,"},{"v":29,"t":"Jarmut s pašnjacima i En-Ganim s pašnjacima. Dakle, četiri grada."},{"v":30,"t":"Od plemena Ašerova: Mišal s pašnjacima, Abdon s pašnjacima,"},{"v":31,"t":"Helkat s pašnjacima i Rehob s pašnjacima. Dakle, četiri grada."},{"v":32,"t":"Od plemena Naftalijeva: grad-utočište Kedeš u Galileji s pašnjacima, Hamot Dor s pašnjacima i Kartan s pašnjacima. Dakle, tri grada."},{"v":33,"t":"Svega Geršonovih gradova po porodicama njihovim bijaše trinaest gradova s pašnjacima."},{"v":34,"t":"Porodicama sinova Merarijevih, preostalim levitima, dali su od plemena Zebulunova: Jokneam s pašnjacima, Kartu s pašnjacima,"},{"v":35,"t":"Rimon s pašnjacima, Nahalal s pašnjacima. Dakle, četiri grada."},{"v":36,"t":"S onu stranu Jordana od plemena Rubenova dadoše im grad-utočište Beser s pašnjacima na pustinjskoj visoravni, Jahas s pašnjacima,"},{"v":37,"t":"Kedemot s pašnjacima, Mefaat s pašnjacima. Dakle, četiri grada."},{"v":38,"t":"Od plemena Gadova: grad-utočište Ramot u Gileadu s pašnjacima, Mahanajim s pašnjacima,"},{"v":39,"t":"Hešbon s pašnjacima, Jazer s pašnjacima. Dakle, četiri grada."},{"v":40,"t":"U svemu bijaše dodijeljeno ždrijebom porodicama sinova Merarijevih, preostalim levitima, dvanaest gradova."},{"v":41,"t":"Tako usred baštine sinova Izraelovih bijaše četrdeset i osam levitskih gradova s pašnjacima."},{"v":42,"t":"Svaki je taj grad imao pašnjake unaokolo. Tako je bilo sa svima spomenutim gradovima."},{"v":43,"t":"Tako je Jahve predao Izraelcima svu zemlju za koju se zakleo da će je dati ocima njihovim. Primili su je u posjed i nastanili se u njoj."},{"v":44,"t":"I dade im Jahve da otpočinu u miru na svim međama, kako se bijaše zakleo njihovim ocima. Nitko im od njihovih neprijatelja ne bijaše kadar odoljeti. Sve im je njihove neprijatelje predao Jahve u ruke."},{"v":45,"t":"Od svih obećanja što ih je Jahve dao domu Izraelovu nijedno ne osta neispunjeno. Sve se ispunilo."}]},"22":{"hr":[{"v":1,"t":"Tada sazove Jošua sinove Rubenove i Gadove i polovinu plemena Manašeova"},{"v":2,"t":"i reče im: “Izvršili ste sve što vam je Mojsije, sluga Jahvin, zapovjedio i poslušali ste me u svemu što sam vam zapovjedio."},{"v":3,"t":"Niste ostavili svoje braće unatoč dugom vojevanju do današnjega dana i vršili ste vjerno zapovijedi Jahve, Boga svojega."},{"v":4,"t":"Sada je Jahve, Bog vaš, dao mir braći vašoj, kako im bijaše obećao. Vratite se sada u svoje šatore, u zemlju koju vam je dao Mojsije, sluga Jahvin, u baštinu s onu stranu Jordana."},{"v":5,"t":"Samo pazite da vršite zapovijedi i Zakon što vam ga dade Mojsije, sluga Jahvin: da ljubite Jahvu, Boga svojega, da uvijek idete putovima njegovim, da čuvate zapovijedi njegove, da se držite uz njega i da mu služite svim srcem i svom dušom.”"},{"v":6,"t":"I blagoslovi ih Jošua i otpusti, a oni se zatim vrate u svoje šatore."},{"v":7,"t":"Mojsije bijaše jednoj polovini plemena Manašeova dao baštinu u Bašanu; a drugoj polovini dade je Jošua usred njihove braće zapadno od Jordana. Otpuštajući ih u njihove šatore, Jošua ih blagoslovi."},{"v":8,"t":"I reče im: “Vratite se u svoje šatore s velikim blagom i s mnogom stokom, sa srebrom, zlatom, tučem, željezom i haljinama u izobilju i podijelite plijen od neprijatelja svojih s braćom svojom.”"},{"v":9,"t":"Vratiše se sinovi Rubenovi i sinovi Gadovi i polovina plemena Manašeova; odoše od sinova Izraelovih iz Šila u zemlji kanaanskoj da krenu u zemlju gileadsku, na svoju baštinu koju su zaposjeli, kako im je zapovjedio Jahve preko Mojsija."},{"v":10,"t":"Kad su stigli do jordanskog područja u zemlji kanaanskoj, podigoše sinovi Rubenovi, sinovi Gadovi i polovina plemena Manašeova žrtvenik na Jordanu, žrtvenik velik, izdaleka se vidio."},{"v":11,"t":"Čuli Izraelci gdje se govori: “Evo, sinovi Rubenovi, sinovi Gadovi i polovina plemena Manašeova podigoše žrtvenik prema zemlji kanaanskoj, kod Jordana, na izraelskoj strani.”"},{"v":12,"t":"Na to se skupi sva zajednica sinova Izraelovih u Šilu da pođu u boj na njih."},{"v":13,"t":"Izraelci sinovima Rubenovim, sinovima Gadovim i polovini plemena Manašeova u gileadsku zemlju poslaše Pinhasa, sina svećenika Eleazara,"},{"v":14,"t":"i s njime deset knezova, po jednoga rodovskog glavara od svakoga plemena Izraelova, a svaki je od njih bio glavar obitelji među tisućama porodica Izraelovih."},{"v":15,"t":"I kad oni dođoše k sinovima Rubenovim, sinovima Gadovim i polovini plemena Manašeova u zemlju gileadsku, rekoše im:"},{"v":16,"t":"“Evo što veli sva zajednica Jahvina: 'Što znači nevjera koju činite protiv Jahve, Boga Izraelova? Zašto se odvrgoste danas od Jahve i, podigavši žrtvenik, zašto se bunite protiv Jahve?"},{"v":17,"t":"Zar vam nije dosta zločina iz Peora, od kojega se nismo očistili do dana današnjega i zbog kojega je došao pomor na zajednicu Jahvinu?"},{"v":18,"t":"Ako se danas odvraćate od Jahve i bunite se danas protiv njega, neće li se sutra izliti njegov gnjev na svu zajednicu Izraelovu?"},{"v":19,"t":"Ili vam je možda zemlja vaše baštine nečista? Onda prijeđite u zemlju baštine Jahvine, u kojoj je Jahvino Prebivalište, i prebivajte među nama. Ali se ne bunite protiv Jahve i ne bunite se protiv nas dižući sebi žrtvenik mimo žrtvenik Jahve, Boga našega."},{"v":20,"t":"Nije li se Akan, Zerahov sin, sam ogriješio o 'herem' te se oborila srdžba na svu zajednicu Izraelovu? Zar nije umro zbog krivice svoje?'”"},{"v":21,"t":"Tada odgovoriše sinovi Rubenovi, sinovi Gadovi i polovina plemena Manašeova govoreći plemenskim glavarima Izraelovim:"},{"v":22,"t":"“Bog, Bog Jahve, Bog nad bogovima, Jahve zna i neka zna Izrael: ako je to bila pobuna ili nevjernost prema Jahvi, neka nam uskrati svoju pomoć danas;"},{"v":23,"t":"ako smo podigli žrtvenik da se odvrgnemo od Jahve i da prinosimo žrtve paljenice, prinosnice i žrtve pričesnice, neka nam onda sudi Jahve!"},{"v":24,"t":"Učinismo to od brige i skrbi i rekosmo: 'Jednoga će dana sinovi vaši reći našima: Što vam je zajedničko s Jahvom, Bogom Izraelovim?"},{"v":25,"t":"Zar nije, sinovi Rubenovi i sinovi Gadovi, postavio Jahve između vas i nas među našu - Jordan? Vi nemate dijela s Jahvom.' I tako bi sinovi vaši mogli učiniti da se sinovi naši odvrate te ne štuju Jahvu."},{"v":26,"t":"Zato smo rekli: 'Podignimo žrtvenik, ali ne za žrtve paljenice niti za klanice,"},{"v":27,"t":"nego da bude svjedočanstvo između nas i vas, među potomcima našim, da želimo služiti Jahvi paljenicama, klanicama i pričesnicama. Tako da ne mognu jednom vaši sinovi reći našima: Nemate dijela s Jahvom.'"},{"v":28,"t":"Ako bi kada tako rekli nama i potomcima našim, mogli bismo odgovoriti: 'Pogledajte slog žrtvenika Jahvina što su ga podigli oci naši ne za žrtve paljenice ni klanice, nego za svjedočanstvo između nas i vas.'"},{"v":29,"t":"Nije nam ni na kraj pameti pomisao da se bunimo protiv Jahve i da se odvraćamo od njega dižući žrtvenik za žrtve paljenice, prinosnice i klanice, mimo žrtvenik Jahve, Boga našega, koji je pred njegovim Prebivalištem!”"},{"v":30,"t":"Kad svećenik Pinhas, knezovi zbora i glavari izraelskih plemena koji su bili s njim čuše riječi koje im rekoše sinovi Gadovi, sinovi Rubenovi i sinovi Manašeovi, umiriše se."},{"v":31,"t":"Tada svećenik Pinhas, sin Eleazarov, odgovori sinovima Rubenovim, sinovima Gadovim i sinovima Manašeovim: “Spoznali smo sada da je Jahve među nama, jer mu se niste iznevjerili: tako ste sačuvali sinove Izraelove od kazne Jahvine.”"},{"v":32,"t":"Svećenik Pinhas, sin Eleazarov, i knezovi odoše od sinova Rubenovih i sinova Gadovih i vratiše se iz zemlje gileadske u kanaansku k sinovima Izraelovim i kazaše im odgovor."},{"v":33,"t":"Izraelovim sinovima bijaše drag taj odgovor: hvalili su Boga i odustali su od nauma da udare na njih i da opustoše zemlju u kojoj su živjeli sinovi Rubenovi i sinovi Gadovi."},{"v":34,"t":"Sinovi Rubenovi i sinovi Gadovi nazvali su žrtvenik “Ed” - “Svjedočanstvo”, jer rekoše: “To je svjedočanstvo među nama: Jahve je Bog.”"}]},"23":{"hr":[{"v":1,"t":"Proteklo je mnogo dana kako je Jahve dao Izraelu da otpočine od svih neprijatelja unaokolo. I Jošua bijaše ostario, zašao u godine."},{"v":2,"t":"Dozva zato Jošua sve Izraelce, starješine, glavare, suce i upravitelje njihove i reče im: “Ostario sam i odmakao u godinama."},{"v":3,"t":"Vi ste bili svjedoci svega što je Jahve, Bog vaš, pred vašim očima učinio svim narodima radi vas: Jahve, Bog vaš, borio se za vas."},{"v":4,"t":"Vidite, razdijelio sam ždrijebom u baštinu vašim plemenima sve narode koji su ostali i sve one narode koje sam istrijebio od Jordana do Velikog mora na zapadu."},{"v":5,"t":"Jahve, Bog vaš, sam će ih goniti ispred vas i otjerat će ih ispred vas i zaposjest ćete njihovu zemlju, kao što vam je obećao Jahve, Bog vaš."},{"v":6,"t":"Budite, dakle, postojani i sve čvršći u tome da čuvate i vršite sve što je napisano u Knjizi zakona Mojsijeva i da ne odstupite od toga ni desno ni lijevo."},{"v":7,"t":"Ne miješajte se s tim narodima koji ostadoše među vama; i ne spominjite imena njihovih bogova niti se kunite njima; nemojte im služiti i ne klanjajte se njima."},{"v":8,"t":"Nego se držite Jahve, Boga svoga, kako ste činili do danas."},{"v":9,"t":"Jahve je protjerao ispred vas velike i moćne narode i nitko se nije do danas mogao održati pred vama."},{"v":10,"t":"Jedan je od vas tjerao pred sobom tisuću, jer se Jahve, Bog vaš, borio za vas, kao što vam je obećao."},{"v":11,"t":"Brižno pazite da ljubite Jahvu, Boga svojega, jer se radi o vašem životu."},{"v":12,"t":"Jer ako se odmetnete i prionete uz ostatak onih naroda koji preostaše među vama i s njima se povežete tazbinom i pomiješate se s njima i oni s vama,"},{"v":13,"t":"znajte dobro da će Jahve, Bog vaš, prestati goniti te narode ispred vas; oni će vam postati zamka i mreža, bit će bič bokovima vašim i trnje očima vašim, sve dok se ne iselite iz ove dobre zemlje koju vam dade Jahve, Bog vaš."},{"v":14,"t":"Evo, ja krećem danas na put kojim je svima poći. Spoznajte i priznajte svim srcem svojim i svom dušom svojom: ni jedno od svih obećanja koja vam je dao Jahve, Bog vaš, nije ostalo neispunjeno."},{"v":15,"t":"I kao što vam se ispunilo svako obećanje što vam ga je dao Jahve, Bog vaš, tako će Jahve ispuniti i svaku prijetnju dok vas ne izbriše s lica ove dobre zemlje koju vam je dao Jahve, Bog vaš."},{"v":16,"t":"Ako prekršite Savez koji je Jahve, Bog vaš, sklopio s vama; ako budete služili drugim bogovima i klanjali se njima, buknut će gnjev Jahvin na vas i nestat će vas ubrzo iz dobre zemlje koju vam je Jahve dao.”"}]},"24":{"hr":[{"v":1,"t":"Jošua potom sabra sva plemena Izraelova u Šekem; i sazva starješine Izraelove, glavare, suce i upravitelje njihove i oni stadoše pred Bogom."},{"v":2,"t":"Tada reče Jošua svemu narodu: “Ovako veli Jahve, Bog Izraelov: 'Nekoć su oci vaši, Terah, otac Abrahamov i Nahorov, živjeli s onu stranu Rijeke i služili drugim bogovima."},{"v":3,"t":"Ali sam ja uzeo oca vašega Abrahama s one strane Rijeke i proveo ga kroza svu zemlju kanaansku, umnožio mu potomstvo i dao mu Izaka."},{"v":4,"t":"Izaku dadoh Jakova i Ezava. Ezavu sam dao goru Seir u posjed. Jakov i sinovi njegovi otišli su u Egipat."},{"v":5,"t":"Tada sam poslao Mojsija i Arona i udario sam Egipat kaznama koje sam učinio u njemu i tada sam vas izveo."},{"v":6,"t":"Izveo sam oce vaše iz Egipta i stigli su na more; Egipćani su progonili vaše oce bojnim kolima i konjanicima sve do Mora crvenoga."},{"v":7,"t":"Zavapili su tada Jahvi i on je razvukao gustu maglu između njih i Egipćana i naveo ih u more koje ih je prekrilo. Vidjeli ste svojim očima što sam učinio Egipćanima; zatim ste ostali dugo vremena u pustinji."},{"v":8,"t":"Nato sam vas uveo u zemlju Amorejaca, koji žive s onu stranu Jordana. Zaratiše s vama i ja ih dadoh u vaše ruke; uzeli ste u baštinu zemlju njihovu jer sam ih ja ispred vas uništio."},{"v":9,"t":"Tada se digao moapski kralj Balak, sin Siporov, da ratuje s Izraelom i on pozva Bileama, sina Beorova, da vas prokune."},{"v":10,"t":"Ali ja ne htjedoh poslušati Bileama: morade vas on i blagosloviti, i spasih vas iz njegove ruke."},{"v":11,"t":"Onda ste prešli preko Jordana i došli u Jerihon, ali su glavari Jerihona poveli rat protiv vas - kao i Amorejci, Perižani, Kanaanci, Hetiti, Girgašani, Hivijci i Jebusejci - ali sam ih ja predao u vaše ruke."},{"v":12,"t":"Pred vama sam poslao stršljene koji su ispred vas tjerali dva kralja amorejska: nemaš što zahvaliti svome maču ni svome luku."},{"v":13,"t":"Dao sam vam zemlju za koju se niste trudili i gradove koje niste gradili i u njima se nastaniste; i vinograde vam dadoh i maslinike koje niste sadili, a danas vas hrane.'"},{"v":14,"t":"I zato se sada bojte Jahve i služite mu savršeno i vjerno! Uklonite bogove kojima su služili oci vaši s onu stranu Rijeke i u Egiptu i služite Jahvi!"},{"v":15,"t":"Međutim, ako vam se ne sviđa služiti Jahvi, onda danas izaberite kome ćete služiti: možda bogovima kojima su služili vaši oci s onu stranu Rijeke ili bogovima Amorejaca u čijoj zemlji sada prebivate. Ja i moj dom služit ćemo Jahvi.”"},{"v":16,"t":"Narod odgovori: “Daleko neka je od nas da ostavimo Jahvu a služimo drugim bogovima."},{"v":17,"t":"Jahve, Bog naš, izveo je nas i naše oce iz Egipta, iz doma robovanja, i on je pred našim očima učinio velika čudesa i čuvao nas cijelim putem kojim smo išli i među svim narodima kroz koje smo prolazili."},{"v":18,"t":"Još više: Jahve je ispred nas protjerao sve narode i Amorejce, koji su živjeli u ovoj zemlji. I mi ćemo služiti Jahvi jer je on Bog naš.”"},{"v":19,"t":"Tada reče Jošua narodu: “Vi ne možete služiti Jahvi, jer je on Bog sveti, Bog ljubomorni, koji ne može podnijeti vaših prijestupa ni vaših grijeha."},{"v":20,"t":"Ako ostavite Jahvu da biste služili tuđim bogovima, okrenut će se protiv vas i uništit će vas, pošto vam je bio dobro činio.”"},{"v":21,"t":"A narod odgovori Jošui: “Ne, mi ćemo služiti Jahvi!”"},{"v":22,"t":"Na to će Jošua narodu: “Sami ste protiv sebe svjedoci da ste izabrali Jahvu da mu služite.” Odgovoriše mu: “Svjedoci smo.”"},{"v":23,"t":"“Maknite, dakle, tuđe bogove koji su među vama i priklonite svoja srca Jahvi, Bogu Izraelovu.”"},{"v":24,"t":"Odgovori narod Jošui: “Služit ćemo Jahvi, Bogu svojemu, i glas ćemo njegov slušati.”"},{"v":25,"t":"Tako sklopi Jošua toga dana Savez s narodom i utvrdi mu uredbu i zakon. Bilo je to u Šekemu."},{"v":26,"t":"Jošua upisa te riječi u Knjigu zakona Božjega. Zatim uze velik kamen i stavi ga ondje pod hrast koji bijaše u svetištu Jahvinu."},{"v":27,"t":"Zatim reče Jošua svemu narodu: “Gle, ovaj kamen neka nam bude svjedokom jer je čuo riječi što ih je govorio Jahve; on će biti svjedok da ne zatajite Boga svoga.”"},{"v":28,"t":"Tada Jošua otpusti narod, svakoga na njegovu baštinu."},{"v":29,"t":"Poslije ovih događaja umrije Jošua, sin Nunov, sluga Jahvin, u dobi od sto deset godina."},{"v":30,"t":"Sahraniše ga u kraju što ga je baštinio u Timnat Serahu, u Efrajimovoj gori, sjeverno od gore Gaaša."},{"v":31,"t":"Izrael je služio Jahvi svega vijeka Jošuina i svega vijeka starješina koje su Jošuu nadživjele i vidjele sva djela što ih je Jahve učinio Izraelu."},{"v":32,"t":"Kosti Josipove, koje su sinovi Izraelovi sa sobom donijeli iz Egipta, pokopali su u Šekemu, na zemljištu koje Jakov bijaše kupio od sinova Hamora, oca Šekemova, za stotinu srebrnjaka i koje je pripalo u baštinu sinova Josipovih."},{"v":33,"t":"Umrije i Eleazar, sin Aronov, i pokopaše ga u Gibei, koja je pripadala njegovu sinu Pinhasu a nalazila se u Efrajimovoj gori."}]}},"JDG":{"1":{"hr":[{"v":1,"t":"Poslije smrti Jošuine upitaše Izraelci Jahvu: “Tko će od nas prvi poći na Kanaance da se protiv njih bori?”"},{"v":2,"t":"A Jahve odgovori: “Neka Juda prvi pođe; u njegove ruke stavljam zemlju.”"},{"v":3,"t":"Tada Juda reče svome bratu Šimunu: “Pođi sa mnom u zemlju koja mi je dosuđena u baštinu; borit ćemo se protiv Kanaanaca, a potom ću se ja uza te boriti na tvojoj zemlji.” I Šimun ode s njim."},{"v":4,"t":"Ode Juda i Jahve im predade u ruke Kanaance i Perižane te pobiše u Bezeku deset tisuća ljudi."},{"v":5,"t":"U Bezeku zatekoše Adoni-Sedeka, udariše na nj i poraziše Kanaance i Perižane."},{"v":6,"t":"Kad je Adoni-Sedek nagnuo u bijeg, gonili su ga, uhvatili ga i odsjekli mu palce na rukama i nogama."},{"v":7,"t":"Tada reče Adoni-Sedek: “Sedamdeset kraljeva odsječenih palaca na rukama i na nogama kupilo je mrvice pod mojim stolom. Kako sam činio, tako mi Bog vraća.” Odveli su ga u Jeruzalem i ondje je umro."},{"v":8,"t":"Zatim Judini sinovi udariše na Jeruzalem, osvojiše ga, posjekoše mačem žitelje i spališe grad."},{"v":9,"t":"Poslije toga krenuše Judini sinovi da se bore protiv Kanaanaca koji su živjeli u Gorju, Negebu i u Šefeli."},{"v":10,"t":"Onda Juda ode na Kanaance koji su živjeli u Hebronu - Hebronu bijaše nekoć ime Kirjat Arba - i ondje potuče Šešaja, Ahimana i Talmaja."},{"v":11,"t":"Odatle krenu na stanovnike Debira, koji se nekoć zvao Kirjat Sefer."},{"v":12,"t":"Tada reče Kaleb: “Tko pokori i zauzme Kirjat Sefer, dat ću mu svoju kćer Aksu za ženu.”"},{"v":13,"t":"Zauze ga Otniel, sin Kenaza, mlađeg brata Kalebova, i Kaleb mu dade svoju kćer Aksu za ženu."},{"v":14,"t":"Kad je prišla mužu, on je nagovori da u svoga oca ište polje. Siđe ona s magarca, a Kaleb je upita: “Što hoćeš?”"},{"v":15,"t":"Ona mu odgovori: “Daj mi blagoslov! Kad si mi dao kraj u Negebu, daj mi onda i koji izvor vode.” I Kaleb joj dade Gornje i Donje izvore."},{"v":16,"t":"Sinovi Hobaba Kenijca, tasta Mojsijeva, odoše iz Palmova grada s Judinim sinovima u Judinu pustinju, koja je u Negebu, na jugu od Arada. Tu se nastaniše među Amalečanima."},{"v":17,"t":"Potom ode Juda s bratom Šimunom i pobiše Kanaance koji su živjeli u Sefatu i grad izručiše “heremu”, prokletstvu. Zbog toga se grad prozva Horma."},{"v":18,"t":"Ali Juda nije uspio zauzeti Gaze s njenim područjem, ni Aškelona s njegovim područjem, ni Ekrona s njegovim područjem."},{"v":19,"t":"Jahve bijaše s njim te on osvoji gorje, ali ne mogaše potjerati onih u nizini jer imahu željezna kola."},{"v":20,"t":"Kao što bijaše odredio Mojsije, dadoše Hebron Kalebu, koji iz njega otjera tri sina Anakova."},{"v":21,"t":"A Benjaminovi sinovi ne uspješe otjerati Jebusejaca koji su živjeli u Jeruzalemu i tako Jebusejci ostadoše u Jeruzalemu s Benjaminovim sinovima do dana današnjega."},{"v":22,"t":"Krenu i pleme Josipovo na Betel i Jahve bijaše s njima."},{"v":23,"t":"I pleme Josipovo uze izviđati Betel. Grad se nekoć zvao Luz."},{"v":24,"t":"Uhode opaziše čovjeka gdje izlazi iz grada i rekoše mu: “Pokaži nam kuda se može u grad, pa ćemo ti biti milostivi.”"},{"v":25,"t":"On im pokaza kuda mogu u grad. I sve u gradu isjekoše mačem, a onoga čovjeka sa svom njegovom obitelji pustiše da ode."},{"v":26,"t":"Čovjek je otišao u zemlju Hetita i ondje sagradio grad i prozvao ga Luz. Tako se zove još i danas."},{"v":27,"t":"Manaše nije osvojio Bet-Šeana i njegovih sela ni Tanaka i njegovih sela. Nije potjerao ni stanovnika iz Dora i njegovih sela, ni stanovnika Jibleama i njegovih sela, ni stanovnika Megida i njegovih sela. Tako su Kanaanci ostali i živjeli u toj zemlji."},{"v":28,"t":"Kad je Izrael ojačao, nametnuo je Kanaancima tlaku, ali ih nije mogao otjerati."},{"v":29,"t":"Ni Efrajim nije otjerao Kanaanaca koji su živjeli u Gezeru, tako te su Kanaanci tu živjeli među njima."},{"v":30,"t":"Zebulun nije otjerao stanovnika Kitrona ni stanovnika Nahalola. Tako su Kanaanci ostali usred Zebulunovih sinova, ali im bijaše nametnuta tlaka."},{"v":31,"t":"Ni Ašer nije otjerao stanovnika Akona, ni stanovnika Sidona, ni onih iz Mahalaba, Akziba, Helbe, Afika i Rehoba."},{"v":32,"t":"Ašerovci su ostali tako među Kanaancima, stanovnicima te zemlje, jer ih nisu otjerali."},{"v":33,"t":"Naftali nije otjerao stanovnika Bet-Šemeša i Bet-Anata, nego je živio među Kanaancima koji su nastavali tu zemlju, ali je stanovnicima Bet-Šemeša i Bet-Anata nametnuta tlaka."},{"v":34,"t":"Amorejci su potisnuli Danove sinove u goru i nisu ih puštali da siđu u ravnicu."},{"v":35,"t":"Amorejci su se zadržali u Har-Heresu, Ajalonu i Šaalbimu, ali kad je ruka Josipova doma ojačala, bila im je nametnuta tlaka."},{"v":36,"t":"Područje Edomaca pruža se od Akrabimskog uspona do Stijene pa naviše."}]},"2":{"hr":[{"v":1,"t":"Anđeo Jahvin dođe iz Gilgala u Bokim i reče: “Izveo sam vas iz Egipta i doveo vas u zemlju koju sam vam obećao zaklevši se ocima vašim. Rekao sam: 'Neću raskinuti Saveza svog s vama dovijeka."},{"v":2,"t":"A vi ne sklapajte saveza sa stanovnicima ove zemlje; nego rušite njihove žrtvenike!' Ali vi niste poslušali moga glasa. Što ste učinili?"},{"v":3,"t":"Zato vam kažem: neću ih odagnati pred vama. Nego, oni će vas tlačiti i bogovi njihovi bit će vam zamkom.”"},{"v":4,"t":"Kad Anđeo Jahvin izreče te riječi svim Izraelcima, narod zakuka i zaplaka."},{"v":5,"t":"I tako prozvaše ono mjesto Bokim i ondje prinesoše žrtve Jahvi."},{"v":6,"t":"Tada Jošua otpusti narod i raziđoše se Izraelci svaki na svoju baštinu da zaposjednu zemlju."},{"v":7,"t":"Narod je služio Jahvi svega vijeka Jošuina i svega vijeka starješina koje su nadživjele Jošuu i vidjele sva velika djela što ih je Jahve učinio Izraelu."},{"v":8,"t":"Jošua, sin Nunov, sluga Jahvin, umrije u dobi od sto deset godina."},{"v":9,"t":"Sahraniše ga u kraju što ga je baštinio u Timnat Heresu, u Efrajimovoj gori, sjeverno od planine Gaaša."},{"v":10,"t":"A kada se sav onaj naraštaj pridružio svojim ocima, naslijedi ga drugi naraštaj koji nije mario za Jahvu ni za djela što ih je učinio Izraelu."},{"v":11,"t":"Tada su sinovi Izraelovi počeli činiti ono što Jahvi nije po volji i služili su baalima."},{"v":12,"t":"Ostaviše Jahvu, Boga otaca svojih, koji ih je izveo iz zemlje egipatske, i pođoše za drugim bogovima između bogova okolnih naroda. Klanjahu im se, razgnjeviše Jahvu."},{"v":13,"t":"Otpali su od Jahve da bi služili Baalu i Aštarti."},{"v":14,"t":"Zato Jahve izli gnjev svoj na Izraela: prepusti ih pljačkašima da ih plijene, izruči ih neprijateljima uokolo, tako te se ne mogoše oduprijeti."},{"v":15,"t":"Što bi god počeli, ruka se Jahvina okretala protiv njih na njihovu nesreću, kao što im je Jahve rekao i kao što im se zakleo. I tako zapadoše u veliku nevolju."},{"v":16,"t":"Tada im Jahve stade podizati suce da ih izbavljaju iz ruku onih koji su ih pljačkali."},{"v":17,"t":"Ali oni ni svojih sudaca nisu slušali, nego se iznevjeriše s drugim bogovima te im se klanjahu. Brzo su zašli s puta kojim su išli oci njihovi slušajući Jahvine zapovijedi; oni nisu činili tako."},{"v":18,"t":"Kada im je podizao suce, Jahve bijaše sa svakim sucem te ih izbavljaše iz ruku njihovih neprijatelja za svega vijeka sučeva, jer se sažalilo Jahvi koliko su uzdisali pod jarmom onih koji su ih ugnjetavali."},{"v":19,"t":"A kada bi sudac umro, oni bi opet zapadali u veću pokvarenost nego njihovi oci. Išli su za drugim bogovima, služili im i klanjali im se, ne odustajući od svojih opakih djela i postupaka."},{"v":20,"t":"Tada Jahve planu gnjevom na Izraela i reče: “Kad je taj narod pogazio Savez kojim sam obvezao njihove očeve i nije poslušao glasa moga,"},{"v":21,"t":"ni ja odsad neću pred njim potjerati ni jednoga između naroda što ih je Jošua po svojoj smrti ostavio”,"},{"v":22,"t":"da bi njima stavio na kušnju Izraela: hoće li se ili neće držati Jahvinih putova kao što ih se držahu oci njihovi."},{"v":23,"t":"Zato Jahve bijaše ostavio te narode i nije ih odmah izagnao ni predao Jošui u ruke."}]},"3":{"hr":[{"v":1,"t":"Ovo su narodi koje je Jahve pustio da ostanu kako bi njima iskušavao sinove Izraelove, sve one koji ne iskusiše ratova kanaanskih."},{"v":2,"t":"Bijaše to samo na korist pokoljenjima sinova Izraelovih da nauče vještinu ratovanja - barem oni koji nisu iskusili prijašnjih ratova:"},{"v":3,"t":"ostade pet knezova filistejskih i svi Kanaanci, Sidonci i Hivijci koji su živjeli na gori Libanonu od gore Baal-Hermona do ulaza u Hamat."},{"v":4,"t":"Oni su poslužili da se iskuša Izrael: da bi se vidjelo hoće li se držati zapovijedi što ih je Jahve preko Mojsija dao njihovim ocima."},{"v":5,"t":"Tako su Izraelci prebivali usred Kanaanaca, Hetita, Amorejaca, Perižana, Hivijaca i Jebusejaca;"},{"v":6,"t":"ženili se njihovim kćerima i davali svoje kćeri njihovim sinovima i služili njihovim bogovima."},{"v":7,"t":"I činili su Izraelci ono što Jahvi nije bilo po volji. Zaboravili su Jahvu, svoga Boga, da bi služili baalima i aštartama."},{"v":8,"t":"Tada Jahve planu gnjevom na Izraela i dade ih u ruke Kušanu Rišatajimu, kralju edomskom; i služiše Kušanu Rišatajimu osam godina."},{"v":9,"t":"Tad Izraelci zavapiše Jahvi i Jahve im podiže izbavitelja, Otniela, sina Kenaza, mlađega brata Kalebova, da ih oslobodi."},{"v":10,"t":"Duh Jahvin siđe na nj i on posta sucem Izraelu. I povede Izraela u boj. Jahve mu preda u ruke Kušana Rišatajima, kralja edomskog, i on pobijedi Kušana Rišatajima."},{"v":11,"t":"Zemlja je otad bila u miru četrdeset godina. Poslije smrti Otniela, sina Kenazova,"},{"v":12,"t":"Izraelci su počeli opet činiti što je zlo u očima Jahvinim. Zato Jahve dade Eglonu, kralju moapskom, moć nad Izraelom, jer su činili što je zlo pred Jahvom."},{"v":13,"t":"Eglon se ujedini sa sinovima Amonovim i Amalekovim, pođe na Izraela, potuče ga i osvoji Palmov grad."},{"v":14,"t":"Izraelci su služili moapskom kralju Eglonu osamnaest godina."},{"v":15,"t":"Tada Izraelci zavapiše Jahvi i Jahve im podiže izbavitelja - Ehuda, sina Gere iz Benjaminova plemena, čovjeka koji bijaše ljevak. I poslaše ga Izraelci da im odnese danak Eglonu, kralju moapskom."},{"v":16,"t":"A Ehud načini sebi bodež sa dvije oštrice, lakat dug, i pripasa ga pod haljine uz desno bedro."},{"v":17,"t":"I odnese danak Eglonu, kralju moapskom. Eglon bijaše vrlo debeo."},{"v":18,"t":"Predavši danak, Ehud ode s ljudima koji bijahu donijeli danak."},{"v":19,"t":"Ali kada je došao do idola u blizini Gilgala, vrati se i reče: “Imam ti, kralju, reći jednu tajnu!” Kralj mu odvrati: “Tiho!” I svi koji su uza nj bili izađu."},{"v":20,"t":"Ehud uđe. Kralj je sjedio u hladovitoj gornjoj sobi; bio je sam. Ehud mu reče: “Imam, kralju, za tebe riječ od Boga!” On odmah usta s prijestolja."},{"v":21,"t":"Tad Ehud lijevom rukom trgnu bodež s desnog bedra i satjera mu ga u trbuh."},{"v":22,"t":"Za oštricom uđe sav držak i salo se sklopi za oštricom, jer Ehud nije mogao izvući oštricu iz trbuha. Nečist je izlazila odande."},{"v":23,"t":"Ehud je otišao kroz trijem; za sobom je zatvorio vrata gornje sobe i zaključao ih."},{"v":24,"t":"Kada je on otišao, vrate se sluge da pogledaju. Kako vrata gornje sobe bijahu zaključana, rekoše: “Bit će da je otišao na stranu, u klijet do hladovite sobe.”"},{"v":25,"t":"Čekali su ga dugo, u nedoumici, jer on nije otvarao vrata gornje sobe. Naposljetku uzeše ključ i otvoriše: gospodar im ležao na tlu, mrtav."},{"v":26,"t":"Dok su oni čekali, Ehud je pobjegao, prošao već idole i sklonio se u Seiru."},{"v":27,"t":"Čim dođe u zemlju Izraelovu, zasvira u rog na Efrajimovoj gori; i siđoše Izraelci s njim s gore, a on im stajaše na čelu."},{"v":28,"t":"I reče im: “Pođite za mnom! Jahve vam je u ruke predao Moapce, vaše neprijatelje.” Oni krenuše za njim, zatvoriše Moapcima put preko gazova Jordana i ne dadoše nikome prijeko."},{"v":29,"t":"Pobili su u to vrijeme oko deset tisuća Moabaca, sve kršnih i hrabrih ljudi, i nijedan im nije umakao."},{"v":30,"t":"Toga su dana Moapci potpali pod ruku Izraelovu i zemlja bijaše mirna osamdeset godina."},{"v":31,"t":"Poslije njega bijaše Šamgar, sin Anatov. On je pobio šest stotina Filistejaca ostanom volujskim. Tako je i on spasio Izraela."}]},"4":{"hr":[{"v":1,"t":"Poslije smrti Ehudove Izraelci su opet stali činiti što Jahvi nije po volji"},{"v":2,"t":"i Jahve ih predade u ruke Jabinu, kanaanskom kralju koji je vladao u Hasoru. Vojskovođa vojsci njegovoj bijaše Sisera, koji je živio u Harošetu Poganskom."},{"v":3,"t":"Tad Izraelci zavapiše Jahvi. Jer Jabin imaše devet stotina željeznih bojnih kola i teško je tlačio Izraelce dvadeset godina."},{"v":4,"t":"U to vrijeme Izraelu je sudila proročica Debora, žena Lapidotova."},{"v":5,"t":"Živjela je pod Deborinom palmom između Rame i Betela u Efrajimovoj gori i k njoj su dolazili Izraelci da presuđuje u njihovim sporovima."},{"v":6,"t":"Ona dozva Baraka, sina Abinoamova, iz Naftalijeva Kedeša i reče mu: “Evo što ti Jahve, Bog Izraelov, zapovijeda: 'Idi, kreni na goru Tabor i uzmi sa sobom deset tisuća ljudi između Naftalijevih i Zebulunovih sinova."},{"v":7,"t":"Ja ću k tebi na Kišonski potok privući Siseru, vojskovođu Jabinove vojske, s njegovim bojnim kolima i svim ratnicima te ću ga predati u tvoje ruke.'”"},{"v":8,"t":"Barak joj odgovori: “Ako ti pođeš sa mnom, ići ću; ako li ne pođeš sa mnom, ne idem.”"},{"v":9,"t":"“Idem s tobom”, reče mu ona, “ali na putu kojim ćeš poći slava neće tebi pripasti jer će Jahve ženi predati u ruke Siseru.” Tada Debora ustane i pođe s Barakom u Kedeš."},{"v":10,"t":"Onamo je Barak pozvao Zebuluna i Naftalija. Deset tisuća ljudi pođe za njim, a išla je s njim i Debora."},{"v":11,"t":"Heber Kenijac bijaše se odvojio od Kajina, jednoga od sinova Hababa, tasta Mojsijeva; razapeo je svoj šator kod Hrasta u Saananimu, nedaleko od Kedeša."},{"v":12,"t":"Javiše Siseri da je Barak, sin Abinoamov, izašao na goru Tabor."},{"v":13,"t":"Nato Sisera sabra sva svoja kola, devet stotina željeznih kola, i sve ljude koje je doveo od Harošeta Poganskog do Kišonskog potoka."},{"v":14,"t":"Debora reče Baraku: “Ustani, evo dana kada će Jahve predati Siseru u tvoje ruke! Sam Jahve ide pred tobom!” I Barak siđe s gore Tabora sa deset tisuća ljudi za sobom."},{"v":15,"t":"Jahve zastraši Siseru, sva njegova kola i čitavu njegovu vojsku, koja naže u bijeg pred mačem Barakovim. Sisera siđe sa svojih kola i pobježe pješice."},{"v":16,"t":"Barak je gonio kola i vojsku sve do Harošeta Poganskog. Sva je Siserina vojska pala od oštrog mača i nijedan čovjek nije umakao."},{"v":17,"t":"Sisera je dotle bježao pješice prema šatoru Jaele, žene Hebera Kenijca, jer između Jabina, kralja hasorskog, i kuće Hebera Kenijca bijaše mir."},{"v":18,"t":"Jaela iziđe Siseri u susret i reče mu: “Zaustavi se, gospodaru, svrati se k meni. Ne boj se ničega!” On svrati k njoj pod šator, a ona ga pokri pokrivačem."},{"v":19,"t":"On joj reče: “Daj mi malo vode jer sam žedan.” Ona otvori mijeh s mlijekom, napoji ga i opet ga pokri."},{"v":20,"t":"“Stani na ulazu u šator”, reče joj on, “pa ako tko naiđe i zapita te: 'Ima li tu koga?' ti odgovori: 'Nema!'”"},{"v":21,"t":"A Jaela, žena Heberova, uze šatorski klin i čekić u ruke, tiho mu se približi i zabi mu klin kroza sljepoočice tako da se zario u zemlju. On od iscrpljenosti bijaše tvrdo zaspao i tako umrije."},{"v":22,"t":"I gle, dođe Barak progoneći Siseru. Jaela iziđe preda nj i reče mu: “Dođi da ti pokažem čovjeka koga tražiš.” On uđe k njoj, i gle - Sisera ležaše mrtav, s klinom u sljepoočici."},{"v":23,"t":"Tako je Bog u onaj dan ponizio Jabina, kralja kanaanskog, pred Izraelcima."},{"v":24,"t":"Ruka Izraelaca postajaše sve teža Jabinu, kralju kanaanskom, dok ga nije napokon zatrla."}]},"5":{"hr":[{"v":1,"t":"Toga dana Debora i Barak, sin Abinoamov, zapjevaše ovu pjesmu:"},{"v":2,"t":"Ratoborno rasuše kose borci izraelski i dragovoljno krenu narod: blagoslivljajte Jahvu!"},{"v":3,"t":"Čujte, o kraljevi! Poslušajte, knezovi! Jahvi ja pjesmu pjevam, Jahvu, Boga Izraelova, ja slavim."},{"v":4,"t":"Sa Seira kad si silazio, Jahve, pobjednički kad si kročio iz polja edomskih, sva se zemlja tresla, lila se nebesa, oblaci curkom daždjeli."},{"v":5,"t":"Brda se tresla pred tobom, o Jahve, Jahve, Bože Izraelov!"},{"v":6,"t":"U dane Šamgara, sina Anatova, u dane Jaele opustješe putovi; i oni koji su putovali, obilažahu naokolo."},{"v":7,"t":"Pusta bijahu sela izraelska dok ne ustadoh ja, Debora, dok ne ustadoh kao majka Izraelu."},{"v":8,"t":"Tuđe bogove sebi izabraše, i zato im rat stade pred vrata. Za pet gradova ne bi nijednog štita! Nijednog kralja za četrdeset tisuća u Izraelu!"},{"v":9,"t":"Srce moje kuca za vođe izraelske, za narod što dragovoljno u boj kreće! Blagoslivljajte Jahvu!"},{"v":10,"t":"Vi koji na bijelim jašete magaricama, na sagovima sjedeći, i vi koji hodite putovima, pjevajte,"},{"v":11,"t":"uz povike razdraganih pastira kod pojila. Neka se slave dobročinstva Jahvina i vladavina njegova Izraelom! I narod Jahvin siđe na vrata."},{"v":12,"t":"Probudi se, Deboro, ustani! Ustani, pjesmu zapjevaj! Hrabro! Ustani, Barače, vodi u roblje porobljivače svoje, sine Abinoamov!"},{"v":13,"t":"Tad siđe na vrata Izrael, narod Jahvin pohrli junački."},{"v":14,"t":"Iz Efrajima potekoše u dolinu, za njima stiže među čete tvoje Benjamin. Iz Makira stupaju glavari, iz Zebuluna oni što nose štap zapovjednički."},{"v":15,"t":"Knezovi Jisakarovi s Deborom bjehu, a Naftali pođe s Barakom, pohrli da ga stigne u dolini. Kod Rubenovih potoka dugo se savjetuju."},{"v":16,"t":"Zašto si ostao u torovima da slušaš sred stada svirku frule? Kod Rubenovih potoka dugo se savjetuju."},{"v":17,"t":"Gilead osta s onu stranu Jordana. A zašto je Dan na stranim lađama? Zašto na obali mora Ašer sjedi, mirno prebiva u svojim zaljevima?"},{"v":18,"t":"Zebulun je narod što prkosi smrti s Naftalijem, na visoravnima."},{"v":19,"t":"Došli su kraljevi, boj zametnuli, boj bili kraljevi kanaanski, u Tanaku, na vodi megidskoj, al' ni mrve srebra ne dobiše."},{"v":20,"t":"Sa nebeskih staza vojevahu, vojevahu zvijezde prot' Siseri."},{"v":21,"t":"Sve otplavi potok Kišon, potok Kišon pradavni. Gazi čvrsto, moja dušo!"},{"v":22,"t":"Topot silan odjekuje: jure borci na konjima!"},{"v":23,"t":"“Proklinjite Meroz,” Anđeo će Jahvin, “proklinjite žitelje njegove što Jahvi nisu u pomoć pritekli, u pomoć Jahvi s junacima.”"},{"v":24,"t":"Blagoslovljena među ženama bila Jaela, žena Hebera Kenijca, među ženama šatora nek' je slavljena!"},{"v":25,"t":"On vode zaiska, mlijeka mu ona dade, u zdjelu dragocjenu nali mu povlake."},{"v":26,"t":"Rukom lijevom za klinom segnu, a desnom za čekićem kovačkim. Udari Siseru, glavu mu razmrska, probode mu, razbi sljepoočicu."},{"v":27,"t":"Do nogu pade joj, sruši se, leže, do nogu pade joj, sruši se; i gdje pade, mrtav osta."},{"v":28,"t":"Kroz prozor motri Siserina mati, kroz prozor motri, na rešetku jÓada: “Dugo mu se kola ne vraćaju: što im je zapreg tako spor?”"},{"v":29,"t":"Najmudrija zbori joj dvorkinja, sebi samoj ona odgovara:"},{"v":30,"t":"“Plijen su našli pa ga dijele: po djevojku na ratnika, po djevojku i po dvije, halju-dvije za Siseru, vezen rubac za moj vrat!”"},{"v":31,"t":"Tako neka ginu, Jahve, svi neprijatelji tvoji! A oni koji te ljube nek budu kao sunce kada se diže u svojemu sjaju! I zemlja bijaše mirna četrdeset godina."}]},"6":{"hr":[{"v":1,"t":"Opet su Izraelci činili što je zlo u Jahvinim očima; i Jahve ih predade u ruke Midjancima za sedam godina."},{"v":2,"t":"Teška bijaše ruka Midjanaca nad Izraelom. Da bi izmakli Midjancima, Izraelci se sklanjahu u gorske pukotine, spilje i skrovišta."},{"v":3,"t":"I kada bi Izraelci posijali, dolazili bi na njih Midjanci i Amalečani i sinovi Istoka."},{"v":4,"t":"Utaborivši se na njihovoj zemlji, uništavali bi rod zemlje sve do Gaze. Ne ostavljahu Izraelu ništa da se prehrani, ni ovce ni koze, ni vola ni magarca,"},{"v":5,"t":"jer dolažahu sa svojim stadima i svojim šatorima u takvu mnoštvu kao skakavci; ne bijaše broja njima ni njihovim devama; preplavili bi zemlju, opustošili je."},{"v":6,"t":"Tako su Midjanci bacili Izraela u veliku bijedu te Izraelci zavapiše Jahvi."},{"v":7,"t":"Kad su Izraelci zavapili Jahvi zbog Midjanaca,"},{"v":8,"t":"Jahve posla Izraelcima proroka koji im reče: “Ovako kaže Jahve, Bog Izraelov: 'Ja sam vas izveo iz Egipta, izbavio vas iz kuće ropstva."},{"v":9,"t":"Ja sam vas oslobodio od ruke Egipćana i od ruke svih vaših tlačitelja. Protjerao sam ih pred vama, dao vam njihovu zemlju"},{"v":10,"t":"i rekao vam: Ja sam Jahve, Bog vaš. Ne štujte bogova Amorejaca u kojih zemlji živite. Ali vi ne poslušaste moga glasa.'”"},{"v":11,"t":"Anđeo Jahvin dođe i sjede pod hrast kod Ofre koji pripadaše Joašu Abiezerovu. Njegov sin Gideon vrhao je pšenicu na tijesku da bi je sačuvao od Midjanaca."},{"v":12,"t":"I ukaza mu se Anđeo Jahvin i reče mu: “Jahve s tobom, hrabri junače!”"},{"v":13,"t":"Gideon mu odgovori: “Oh, gospodaru, ako je Jahve s nama, zašto nas sve ovo snađe? Gdje su sva ona čudesa njegova o kojima nam pripovijedahu oci naši govoreći: 'Nije li nas Jahve iz Egipta izveo?' A sada nas je Jahve ostavio, predao nas u ruke Midjancima.”"},{"v":14,"t":"Jahve se tad okrenu prema njemu i reče mu: “Idi s tom snagom u sebi i izbavit ćeš Izraela iz ruke Midjanaca. Ne šaljem li te ja?”"},{"v":15,"t":"“Ali, gospodaru”, odgovori mu Gideon, “kako ću izbaviti Izraela? Moj je rod najmanji u Manašeovu plemenu, a ja sam posljednji u kući svoga oca.”"},{"v":16,"t":"Jahve mu reče: “Ja ću biti s tobom te ćeš pobijediti Midjance kao jednoga.”"},{"v":17,"t":"Gideon mu reče: “Ako sam našao milost u tvojim očima, daj mi znak da ti govoriš sa mnom."},{"v":18,"t":"Nemoj otići odavde dok se ne vratim s darom i stavim ga preda te.” A on odgovori: “Ostat ću dok se ne vratiš.”"},{"v":19,"t":"Gideon ode, zgotovi jare i od efe brašna načini beskvasne hljebove, stavi meso u košaricu i juhu u lonac pa donese sve to pod hrast."},{"v":20,"t":"Anđeo Jahvin reče mu: “Uzmi meso i beskvasne hljebove, stavi ih na tu stijenu, a juhu prolij.” On učini tako."},{"v":21,"t":"Anđeo Jahvin tad uze štap što ga je držao i vrhom dotaknu meso i beskvasne hljebove. Oganj planu iz stijene, spali meso i beskvasne hljebove. Anđeo Jahvin nato iščeze pred njegovim očima."},{"v":22,"t":"Tad Gideon vidje da je to bio Anđeo Jahvin i reče: “Jao, Jahve, Gospode! Anđela Jahvina vidjeh licem u lice!”"},{"v":23,"t":"Jahve mu odgovori: “Mir s tobom! Ne boj se, nećeš umrijeti!”"},{"v":24,"t":"Gideon podiže na tome mjestu žrtvenik Jahvi i nazva ga “Jahve-Mir”. Žrtvenik još i danas stoji u Ofri Abiezerovoj."},{"v":25,"t":"Iste noći Jahve reče Gideonu: “U svojega oca uzmi utovljena junca, junca od sedam godina, i razori Baalov žrtvenik i posijeci gaj pokraj njega."},{"v":26,"t":"Potom podigni žrtvenik Jahvi, Bogu svome, na vrhu te gorske stijene i dobro ga uredi. Uzmi junca i prinesi paljenicu na drvima Ašere što ih u gaju nasiječeš.”"},{"v":27,"t":"Tada Gideon uze deset ljudi između svojih slugu i učini kako mu je zapovjedio Jahve. Ali kako se bojao svoje obitelji i građana, učini to noću."},{"v":28,"t":"Kad su građani sutradan poranili, a to razoren Baalov žrtvenik i gaj posječen pored njega, a junac žrtvovan kao paljenica na novom oltaru."},{"v":29,"t":"I pitahu jedni druge: “Tko je to učinio?” Ispitaše, istražiše pa rekoše: “Gideon, Joašev sin, učini to.”"},{"v":30,"t":"Tada građani rekoše Joašu: “Izvedi sina da umre jer je razorio Baalov žrtvenik i posjekao gaj pored njega.”"},{"v":31,"t":"Joaš odgovori svima koji stajahu oko njega: “Zar ćete vi braniti Baala? Zar ćete ga vi spasavati? Tko brani Baala, bit će pogubljen prije sutrašnjeg dana. Ako je on bog, neka se sam brani od Gideona što mu je razorio žrtvenik.”"},{"v":32,"t":"Toga dana prozvali su Gideona Jerubaal jer se govorilo: “Neka sam Baal s njim obračuna što mu je srušio žrtvenik.”"},{"v":33,"t":"Svi Midjanci, Amalečani i sinovi Istoka bijahu se sakupili i, prešavši Jordan, utaborili se u Jizreelskoj ravnici."},{"v":34,"t":"Duh Jahvin obuze Gideona i on zasvira u rog, a Abiezerov rod stade iza njega."},{"v":35,"t":"Posla on glasnike po svem plemenu Manašeovu te i oni stadoše iza njega. Posla glasnike i u pleme Ašerovo, Zebulunovo i Naftalijevo te im i oni krenuše u susret."},{"v":36,"t":"Gideon reče Bogu: “Ako zaista hoćeš osloboditi Izraela mojom rukom, kao što si obećao,"},{"v":37,"t":"evo ću metnuti ovčje runo na gumno: ako bude rose samo na runu, a zemlja ostane suha, tada ću znati da ćeš mojom rukom izbaviti Izraela, kao što si obećao.”"},{"v":38,"t":"I bi tako. Gideon urani sutradan te iscijedi rosu iz runa - punu zdjelu vode."},{"v":39,"t":"Opet Gideon reče Bogu: “Ne razgnjevi se na me što ti progovaram još jednom. Dopusti mi da još ovaj put pokušam s runom: neka samo runo bude suho, a neka po svoj zemlji bude rosa!”"},{"v":40,"t":"I Bog one noći učini tako: samo je runo ostalo suho, a po svoj zemlji pala rosa."}]},"7":{"hr":[{"v":1,"t":"Urani Jerubaal, to jest Gideon, i sav narod bijaše s njim i utabori se kod En-Haroda; a tabor Midjanaca nalazio se na sjeveru od njegova, podno brijega More, u dolini."},{"v":2,"t":"Tada Jahve reče Gideonu: “Previše je naroda s tobom a da bih predao Midjance u njegove ruke. Izrael bi se mogao pohvaliti i reći: 'Vlastita me ruka izbavila.'"},{"v":3,"t":"Zato oglasi da narod čuje: 'Tko se boji i strahuje, neka se vrati.'” Gideon ih iskuša. Dvadeset i dvije tisuće ljudi iz naroda vrati se, a ostade ih deset tisuća."},{"v":4,"t":"Jahve reče Gideonu: “Još je previše naroda. Povedi ih na vodu i ondje ću ih iskušati. Za koga ti kažem: 'Neka ide s tobom', taj će s tobom ići. A za koga ti kažem: 'Neka ne ide s tobom', taj neće ići.”"},{"v":5,"t":"Gideon povede narod na vodu i Jahve mu reče: “Koji bude laptao vodu jezikom kao što lapće pas, stavi ga na stranu. Koji klekne da pije, odvoji ga na drugu stranu.”"},{"v":6,"t":"Onih koji su laptali vodu jezikom - prinoseći vodu rukom k ustima - bijaše tri stotine, a sav je ostali narod kleknuo da pije."},{"v":7,"t":"Tad Jahve reče Gideonu: “Sa one tri stotine ljudi koji su laptali vodu ja ću vas izbaviti i predat ću Midjance u vaše ruke. Svi drugi neka se vrate svaki svojoj kući.”"},{"v":8,"t":"Gideon tad naloži narodu da mu preda opskrbu i rogove, a onda otpusti Izraelce da ide svaki svome šatoru; zadrža samo one tri stotine. A midjanski se tabor prostirao niže njega u dolini."},{"v":9,"t":"One noći reče mu Jahve: “Ustani, navali na tabor, jer ti ga predajem u ruke."},{"v":10,"t":"Ako se bojiš napasti, siđi najprije u tabor s Purom, momkom svojim;"},{"v":11,"t":"slušaj što govore; ohrabrit ćeš se i napast ćeš na tabor.” On siđe sa svojim momkom Purom do prvih taborskih straža."},{"v":12,"t":"Midjanci, Amalečani i svi sinovi Istoka pali po dolini, brojni kao skakavci; njihovim devama ne bijaše broja, kao pijesku na obali mora."},{"v":13,"t":"Kad je Gideon došao, a to jedan baš pripovijedaše svome drugu što je sanjao: “Usnuo sam kako se pogača ječmenog kruha kotrlja u midjanski tabor: dokotrlja se do jednog šatora i pogodi, a šator pade, prevrnu se.”"},{"v":14,"t":"A drug mu odgovori: “Nije to drugo nego mač Gideona, Joaševa sina, Izraelca. Bog mu je predao u ruke Midjance i sav tabor.”"},{"v":15,"t":"Kada je Gideon čuo kako je onaj pripovjedio san i kako ga je drugi protumačio, baci se ničice, vrati se onda u tabor Izraelov i povika: “Ustajte, jer vam je Jahve predao u ruke tabor midjanski!”"},{"v":16,"t":"Gideon tad podijeli svoje tri stotine ljudi u tri čete. Svakome čovjeku dade u ruke rog, prazan vrč i luč u vrču:"},{"v":17,"t":"“Gledajte mene”, reče im, “i činite što i ja! Kada dođem na rub tabora, činite što budem i ja činio!"},{"v":18,"t":"Kad zatrubim u rog ja i svi koji su sa mnom, tada i vi zasvirajte u rog oko sveg tabora i vičite: 'Za Jahvu i Gideona!'”"},{"v":19,"t":"Gideon i stotina ljudi što ga je pratila dođoše na rub tabora pri početku ponoćne straže; tek što su postavili straže, oni zatrubiše u rogove i razbiše vrčeve koje su imali u ruci."},{"v":20,"t":"Tako tri čete zasviraše u rogove i razbiše vrčeve; lijevom rukom držahu luči, a desnom rogove da trube i udariše vikati: “Za Jahvu i Gideona!”"},{"v":21,"t":"I svaki stajaše nepomično na svome mjestu uokrug tabora. Tada se probudi sav tabor i Midjanci vičući nagoše u bijeg."},{"v":22,"t":"Dok su one tri stotine trubile u rogove, učini Jahve te oni u taboru okrenuše mač jedan na drugoga. I sva se vojska razbježa do Bet-Hašita, prema Sartanu, do Abel-Meholske obale kod Tabata."},{"v":23,"t":"A Izraelci iz plemena Naftalijeva, Ašerova i iz svega plemena Manašeova sabraše se i pognaše Midjance."},{"v":24,"t":"Gideon posla glasnike po svoj Efrajimovoj gori da govore: “Siđite pred Midjance i zauzmite prije njih sve gazove do Bet-Bara i Jordana.” Svi se ljudi od plemena Efrajimova odazvaše i zauzeše gazove voda do Bet-Bara i Jordana."},{"v":25,"t":"I uhvatiše dva midjanska kneza, Oreba i Zeeba; Oreba ubiše na Orebovoj stijeni, a Zeeba kod Zeebova tijeska. Progonili su Midjance i donijeli Gideonu preko Jordana glavu Orebovu i Zeebovu."}]},"8":{"hr":[{"v":1,"t":"Tada Efrajimovi ljudi rekoše Gideonu: “Kako si postupio prema nama: nisi nas pozvao kada si pošao u boj protiv Midjanaca?” I žestoko mu prigovoriše."},{"v":2,"t":"On im odgovori: “Pa što sam ja učinio kad se usporedim s vama? Nije li Efrajimovo pabirčenje bolje od Abiezerove berbe?"},{"v":3,"t":"U vaše je ruke Jahve predao knezove midjanske, Oreba i Zeeba. Može li se usporediti moje djelo s onim što ste vi učinili?” Na te riječi utiša se njihova srdžba prema njemu."},{"v":4,"t":"Kad je Gideon došao do Jordana, prijeđe ga, ali i on i tri stotine ljudi s njim bijahu iznemogli i gladni."},{"v":5,"t":"Stoga reče ljudima iz Sukota: “Dajte kruha ljudima koji idu za mnom, iznemogli su. Ja gonim Zebaha i Salmunu, kraljeve midjanske.”"},{"v":6,"t":"Ali mu sukotski glavari odgovoriše: “Zar je Zebahova i Salmunina šaka već u tvojoj ruci da dademo kruha tvojoj vojsci?”"},{"v":7,"t":"Gideon im reče: “Dobro! Kad mi Jahve preda u ruke Zebaha i Salmunu, iskidat ću vam meso trnjem i dračem pustinjskim.”"},{"v":8,"t":"Odatle ode u Penuel i zatraži isto od Penuelaca, a oni mu odgovore kao što su mu odgovorili i Sukoćani."},{"v":9,"t":"On zaprijeti i Penuelcima: “Kad se vratim kao pobjednik, porušit ću ovu kulu.”"},{"v":10,"t":"Zebah i Salmuna bijahu u Karkoru i vojska njihova s njima, oko petnaest tisuća ljudi, što ih god osta od vojske sinova Istoka; sto dvadeset tisuća ratnika bijaše palo."},{"v":11,"t":"Gideon pođe putem kojim prolaze oni što žive pod šatorima, istočno od Nobaha i Jogbohe, te potuče vojsku kad stajaše bezbrižna."},{"v":12,"t":"Zebah i Salmuna pobjegoše. On ih pogna i uhvati dva kralja midjanska, Zebaha i Salmunu. A vojsku im svu uništi."},{"v":13,"t":"Poslije bitke Gideon, sin Joašev, vrati se preko Hareške uzvisine."},{"v":14,"t":"I uhvati nekog momka iz Sukota te ga uze ispitivati; a on mu popisa imena sukotskih knezova i starješina, sedamdeset i sedam ljudi."},{"v":15,"t":"Potom Gideon ode Sukoćanima i reče: “Evo Zebaha i Salmune zbog kojih ste mi se rugali govoreći: 'Je li Zebahova i Salmunina šaka već u tvojoj ruci pa da dademo kruha tvojim iznemoglim ljudima?'”"},{"v":16,"t":"I uhvati starješine gradske, nabra pustinjskog trnja i drača da ih oćute leđa Sukoćana."},{"v":17,"t":"Poruši Penuelsku kulu i pobi građane."},{"v":18,"t":"Onda reče Zebahu i Salmuni: “Kakvi bijahu ljudi koje pobiste na Taboru?” “Bili su nalik na te”, odgovoriše. “Svaki bijaše kao kraljev sin.”"},{"v":19,"t":"“To su bila moja braća, sinovi moje matere”, reče Gideon. “Tako mi Jahve, da ste ih ostavili na životu, ne bih vas ubio.”"},{"v":20,"t":"Potom zapovjedi svom prvencu Jeteru: “Ustani, pogubi ih!” Ali dječak ne izvuče mača: bojao se, bijaše još mlad."},{"v":21,"t":"Tada rekoše Zebah i Salmuna: “Ustani ti i navali na nas, jer kakav je čovjek, onakva mu i snaga.” I ustavši, Gideon pogubi Zebaha i Salmunu i uze mjesečiće što su visjeli o vratu njihovih deva."},{"v":22,"t":"Izraelci rekoše Gideonu: “Vladaj nad nama, ti, sin tvoj i unuk tvoj, jer si nas ti izbavio iz ruku Midjanaca.”"},{"v":23,"t":"Ali im Gideon odgovori: “Ne, neću ja vladati nad vama, a ni moj sin; Jahve će biti vaš vladar.”"},{"v":24,"t":"Još im reče Gideon: “Jedno samo od vas tražim: da mi svaki dade prsten od svog plijena.” Pobijeđeni su nosili zlatne prstenove jer bijahu Jišmaelci."},{"v":25,"t":"“Vrlo rado”, odgovore oni. On nato razastrije svoj plašt, a svaki od njih baci od svog plijena po prsten."},{"v":26,"t":"Težina zlatnih prestenova što ih je zaiskao iznosila je tisuću i sedam stotina zlatnih šekela, osim mjesečića, naušnica i skrletnih haljina koje su nosili midjanski kraljevi i osim lančića što bijahu oko vrata njihovih deva."},{"v":27,"t":"Gideon načini od toga efod i postavi ga u svome gradu Ofri. I sav Izrael udari za njim u nevjeru i bijaše to zamka Gideonu i njegovu domu."},{"v":28,"t":"Tako su Midjanci bili poniženi pred Izraelcima. Više ne dizahu glave i zemlja bi mirna četrdeset godina, koliko još potraja vijek Gideonov."},{"v":29,"t":"Jerubaal, sin Joašev, otišao je i živio u svojoj kući."},{"v":30,"t":"Gideon je imao sedamdeset sinova koji su potekli od njega jer je imao mnogo žena."},{"v":31,"t":"Njegova inoča koja je živjela u Šekemu rodi mu sina komu nadjenu ime Abimelek."},{"v":32,"t":"Gideon, sin Joašev, umrije u dubokoj starosti; sahraniše ga u grobu njegova oca Joaša u Abiezerovoj Ofri."},{"v":33,"t":"Po Gideonovoj smrti Izraelci okrenuše u preljub s baalima te postaviše sebi za boga Baal-Berita."},{"v":34,"t":"Izraelci se nisu više sjećali Jahve, svoga Boga, koji ih je izbavio iz ruku svih njihovih neprijatelja unaokolo."},{"v":35,"t":"I nisu iskazivali zahvalnost domu Jerubaala Gideona za dobro što ga je učinio Izraelu."}]},"9":{"hr":[{"v":1,"t":"Abimelek, sin Jerubaalov, otiđe u Šekem k braći svoje matere i reče njima i svemu rodu kuće svoje majke:"},{"v":2,"t":"“Upitajte sve šekemske građane: što vam je bolje - da nad vama vlada sedamdeset ljudi, svi sinovi Jerubaalovi, ili jedan čovjek? Sjetite se da sam ja od vašeg mesa i vaših kostiju!”"},{"v":3,"t":"To braća njegove matere prenesoše ostalim šekemskim građanima i njihovo se srce prikloni Abimeleku jer govorahu: “Naš je brat!”"},{"v":4,"t":"I dadoše mu sedamdeset šekela srebra iz hrama Baal-Beritova; time Abimelek unajmi klatež i pustolove koji pođoše za njim."},{"v":5,"t":"Onda dođe u kuću svoga oca u Ofri i pobi svoju braću, sinove Jerubaalove, sedamdeset ljudi, na jednom kamenu. Izmakao mu je samo Jotam, najmlađi sin Jerubaalov jer se bijaše sakrio."},{"v":6,"t":"Tada se skupiše svi šekemski građani i sav Bet-Milo te postaviše Abimeleka za kralja kod hrasta koji stoji u Šekemu."},{"v":7,"t":"Kada su to dojavili Jotamu, ode on, stade na vrh gore Gerizima i povika im na sav glas: “Čujte me, uglednici šekemski, tako vas čuo Bog!"},{"v":8,"t":"Jednom se zaputila stabla da pomažu kralja koji će vladati nad njima. Pa rekoše maslini: 'Budi nam kraljem!'"},{"v":9,"t":"Odgovori im maslina: 'Zar da se svog ulja odreknem što je na čast bozima i ljudima da bih vladala nad drugim drvećem?'"},{"v":10,"t":"Tad rekoše stabla smokvi: 'Dođi, budi nam kraljem!'"},{"v":11,"t":"Odgovori im smokva: 'Zar da se odreknem slatkoće i krasnoga ploda svog da bih vladala nad drugim drvećem?'"},{"v":12,"t":"Tad rekoše stabla lozi: 'Dođi, budi nam kraljem!'"},{"v":13,"t":"Odgovori im loza: 'Zar da se odreknem vina što veseli bogove i ljude da bih vladala nad drugim drvećem?'"},{"v":14,"t":"Sva stabla rekoše tad glogu: 'Dođi, budi nam kraljem!'"},{"v":15,"t":"A glog odgovori stablima: 'Ako me doista hoćete pomazat' za kralja, u sjenu se moju sklonite. Ako nećete, iz gloga će oganj planuti i sažeći cedrove libanonske!'"},{"v":16,"t":"Sada, jeste li vjerno i čestito učinili kad ste izabrali Abimeleka za kralja? Jeste li se dobro ponijeli prema Jerubaalu i njegovoj kući? Jeste li mu uzvratili za djela što ih za vas učini?"},{"v":17,"t":"Moj se otac za vas borio izloživši svoj život te vas izbavio iz ruku Midjanaca,"},{"v":18,"t":"a vi danas ustaste protiv kuće moga oca, pobiste njegove sinove, sedamdeset ljudi na istom kamenu, i nad građanima Šekema učiniste kraljem Abimeleka, sina njegove robinje, zato što je vaš brat!"},{"v":19,"t":"Ako ste vjerno i pošteno danas radili prema Jerubaalu i prema njegovoj kući, radujte se s Abimelekom, a on neka se raduje s vama!"},{"v":20,"t":"Ako niste, neka oganj iziđe iz Abimeleka i sažeže građane Šekema i Bet-Mila i neka iziđe oganj iz građana Šekema i Bet-Mila i sažeže Abimeleka!”"},{"v":21,"t":"Onda Jotam pobježe, skloni se i dođe u Beer, i ondje ostade, jer se bojao svoga brata Abimeleka."},{"v":22,"t":"Abimelek je vladao nad Izraelom tri godine."},{"v":23,"t":"Tada Bog posla duh razdora među Abimeleka i šekemske građane i šekemski se građani pobuniše protiv Abimeleka."},{"v":24,"t":"Bijaše to zato da bi se osvetio zločin počinjen nad sedamdeset Jerubaalovih sinova i da bi njihova krv pala na njihova brata Abimeleka, koji ih ubi, i na građane Šekema, koji mu pomogoše da ubije braću."},{"v":25,"t":"Hoteći mu napakostiti, šekemski su građani postavili zasjede po vrhovima planina i pljačkali svakoga tko bi prošao mimo njih onim putem. Javiše to Abimeleku."},{"v":26,"t":"Gaal, sin Ebedov, dođe sa svojom braćom i nastani se u Šekemu; a šekemski se građani pouzdaše u njega."},{"v":27,"t":"Otišavši u polje, trgali su u svojim vinogradima grožđe i gazili ga, a onda udarili u veselje; ušli su u hram svoga boga, jeli su, pili i proklinjali Abimeleka."},{"v":28,"t":"A Gaal, Ebedov sin, povika: “Tko je Abimelek da mu služimo? Zar ne bi trebalo da Jerubaalov sin i Zebul, njegov namjesnik, služe ljude Hamora, Šekemova oca? Zašto da mi njemu služimo?"},{"v":29,"t":"O, kad bih imao ovaj narod u svojoj ruci, protjerao bih Abimeleka i rekao mu: 'Pojačaj svoju vojsku i iziđi u boj!'”"},{"v":30,"t":"A kad Zebul, gradski načelnik, doznade što je govorio Gaal, sin Ebedov, razgnjevi se."},{"v":31,"t":"Posla glasnike Abimeleku u Arumu i poruči mu: “Evo, Gaal, sin Ebedov, došao u Šekem sa svojom braćom i bune građane protiv tebe."},{"v":32,"t":"Zato ustani noću, ti i narod što je s tobom, i stani u zasjedu u polju."},{"v":33,"t":"A ujutro, kad ograne sunce, digni se i udari na grad. Kada Gaal i njegovi ljudi iziđu preda te, ti učini s njima što ti prilike posavjetuju.”"},{"v":34,"t":"Abimelek usta noću sa svim svojim ljudima i stade u zasjedu oko Šekema u četiri čete."},{"v":35,"t":"Kada je Gaal, sin Ebedov, izišao pred gradska vrata i zaustavio se, Abimelek i njegovi ljudi ustaše iz zasjede."},{"v":36,"t":"Gaal ugleda ljude i reče Zebulu: “Eno silaze ljudi s gorskih vrhova.” “Od sjena gorskih vrhova”, odgovori mu Zebul, “čine ti se ljudi.”"},{"v":37,"t":"Opet progovori Gaal: “Eno silaze ljudi s visa zvana Zemljin pupak, a četa jedna dolazi putem od Čarobnjačkog hrasta.”"},{"v":38,"t":"Tad mu reče Zebul: “Gdje ti je sada jezik? Pa ti si govorio: 'Tko je Abimelek da mu služimo?' Nisu li ondje ljudi koje si prezirao? Iziđi sada i pobij se s Abimelekom.”"},{"v":39,"t":"I Gaal iziđe na čelu šekemskih građana i pobi se s Abimelekom."},{"v":40,"t":"Abimelek potjera Gaala i on pobježe pred njim; i mnogi njegovi ljudi padoše mrtvi prije nego što su i došli do vrata."},{"v":41,"t":"Abimelek se tada vrati u Arumu, a Zebul potjera Gaala i njegovu braću i nije im više dao da ostanu u Šekemu."},{"v":42,"t":"Sutradan je narod izišao u polje i javiše to Abimeleku."},{"v":43,"t":"On uze svoju vojsku, podijeli je u tri čete i stade u zasjedu u polju. Kad bi vidio gdje ljudi izlaze iz grada, nasrnuo bi na njih i pobio ih."},{"v":44,"t":"Dok je Abimelek sa svojom četom udarao kod gradskih vrata, druge se dvije čete baciše na one koji bijahu u polju i tako ih pobiše."},{"v":45,"t":"Čitav je dan Abimelek opsjedao grad. Zauzevši ga, poubija sve stanovništvo, razori grad i posu sol po njemu."},{"v":46,"t":"Kad su to čuli gospodari Migdal Šekema, uđoše svi u tvrdi prostor hrama El-Berita."},{"v":47,"t":"Kada je Abimelek doznao da su se svi građani Migdal Šekema ondje sakupili,"},{"v":48,"t":"popne se na Salmonsku goru sa svom vojskom svojom. Uzevši u ruke sjekiru, odsječe granu od drveta, podiže je i metnu sebi na rame. A ljudima zapovjedi: “Što vidjeste da sam ja učinio, učinite brzo i vi.”"},{"v":49,"t":"I svi ljudi odsjekoše sebi po granu, a onda krenuše za Abimelekom, nabacaše granje na utvrdu i zapališe ga nad onima koji su se ondje nalazili. Tako izgiboše svi žitelji Migdal Šekema, oko tisuću ljudi i žena."},{"v":50,"t":"Potom Abimelek krenu na Tebes, opsjede ga i osvoji."},{"v":51,"t":"Bijaše ondje usred grada kula kamo su se sklonili svi ljudi i žene i svi uglednici gradski. Zatvorivši za sobom vrata, popeše se kuli na krov."},{"v":52,"t":"Abimelek dođe do kule i napade je. Dok je prilazio vratima kule da je zapali,"},{"v":53,"t":"neka žena baci mu žrvanj na glavu i razbi mu lubanju."},{"v":54,"t":"On brzo pozva svoga momka koji mu je nosio oružje i reče mu: “Trgni mač i ubij me da se ne govori o meni: 'Žena ga je ubila.'” Njegov ga momak probode te on umrije."},{"v":55,"t":"Kad su Izraelci vidjeli da je Abimelek mrtav, svi se vratiše svojim kućama."},{"v":56,"t":"Tako je Bog svalio na Abimeleka zlo koje je on učinio svome ocu pobivši sedamdesetero svoje braće."},{"v":57,"t":"I sve zlo Šekemaca Bog svali na njihove glave i tako ih stiže kletva Jotama, sina Jerubaalova."}]},"10":{"hr":[{"v":1,"t":"Poslije Abimeleka ustao je Tola, sin Pue, sina Dodova, da izbavi Izraela. On bijaše iz Jisakarova plemena, a živio je u Šamiru, u Efrajimovoj gori."},{"v":2,"t":"Bio je sudac Izraelu dvadeset i tri godine, a kad je umro, pokopali su ga u Šamiru."},{"v":3,"t":"Poslije njega ustao je Jair Gileađanin, koji je bio sudac Izraelu dvadeset i dvije godine."},{"v":4,"t":"Imao je trideset sinova koji su jahali na tridesetero magaradi i imali trideset gradova što se do dana današnjega zovu Sela Jairova, a nalaze se u gileadskoj zemlji."},{"v":5,"t":"Kad umrije Jair, pokopaše ga u Kamonu."},{"v":6,"t":"Izraelci su opet stali činiti ono što Jahvi nije po volji. Služili su baalima i aštartama, aramejskim bogovima i sidonskim bogovima, bogovima Moabaca, bogovima Amonaca i bogovima Filistejaca. A Jahvu su napustili i nisu mu više služili."},{"v":7,"t":"Tad planu Jahve gnjevom i predade ih u ruke Filistejcima i Amoncima."},{"v":8,"t":"Oni su od tada osamnaest godina satirali i tlačili Izraelce - sve Izraelce koji življahu s onu stranu Jordana, u zemlji amorejskoj, koja je u Gileadu."},{"v":9,"t":"Potom su Amonci prešli Jordan da zavojšte i na Judu, Benjamina i na Efrajima te se Izrael nađe u velikoj nevolji."},{"v":10,"t":"Tada zavapiše Izraelci Jahvi govoreći: “Griješili smo prema tebi jer smo ostavili Jahvu, svoga Boga, da bismo služili baalima.”"},{"v":11,"t":"A Jahve odgovori Izraelcima: “Nisu li vas tlačili Egipćani i Amorejci, Amonci i Filistejci,"},{"v":12,"t":"Sidonci, Amalečani i Midjanci? Ali kad ste zavapili prema meni, nisam li vas izbavio iz njihovih ruku?"},{"v":13,"t":"Ali vi ostaviste mene i uzeste služiti drugim bogovima. Zbog toga vas neću više izbavljati."},{"v":14,"t":"Idite i vapite za pomoć onim bogovima koje ste izabrali! Neka vas oni izbave iz vaše nevolje!”"},{"v":15,"t":"Izraelci odgovoriše Jahvi: “Sagriješili smo! Čini s nama što ti drago, samo nas danas izbavi!”"},{"v":16,"t":"I odstraniše tuđe bogove i počeše opet služiti Jahvi. A Jahve više ne mogaše trpjeti da Izraelci pate."},{"v":17,"t":"Kada su se Amonci sabrali i utaborili u Gileadu, skupiše se i Izraelci i utaboriše se u Mispi."},{"v":18,"t":"Tada narod i knezovi gileadski rekoše jedni drugima: “Koji čovjek povede boj protiv Amonaca, neka bude poglavar svima koji žive u Gileadu.”"}]},"11":{"hr":[{"v":1,"t":"Gileađanin Jiftah bijaše hrabar ratnik. Rodila ga bludnica, a otac mu bijaše Gilead."},{"v":2,"t":"Ali je Gileadu i njegova žena rodila sinove, pa kada su sinovi te žene odrasli, otjeraše Jiftaha govoreći mu: “Nećeš dobiti baštine od našeg oca jer si sin strane žene.”"},{"v":3,"t":"Jiftah zato pobježe od svoje braće i naseli se u zemlji Tobu. Ondje se oko njega okupila hrpa beskućnika koji su s njim pljačkali."},{"v":4,"t":"Poslije nekog vremena Amonci zavojštiše na Izraela."},{"v":5,"t":"Kada su Amonci napali Izraela, krenuše gileadske starješine da trže Jiftaha u zemlji Tobu."},{"v":6,"t":"“Hodi”, rekoše mu, “budi nam vojvoda da ratujemo protiv Amonaca.”"},{"v":7,"t":"Ali Jiftah odgovori gileadskim starješinama: “Niste li me vi mrzili i otjerali iz kuće moga oca? Zašto sada dolazite k meni kada ste u nevolji?”"},{"v":8,"t":"Gileadske starješine rekoše Jiftahu: “Zato smo sada došli tebi: pođi s nama, povedi rat protiv Amonaca i bit ćeš poglavar nama i svima u Gileadu.”"},{"v":9,"t":"Jiftah upita gileadske starješine: “Ako me odvedete natrag da ratujem protiv Amonaca te ako ih Jahve meni preda, hoću li biti vaš poglavar?”"},{"v":10,"t":"“Jahve neka bude svjedokom među nama”, odgovore Jiftahu gradske starješine. “Jao nama ako ne učinimo kako si rekao!”"},{"v":11,"t":"I Jiftah ode sa starješinama Gileada. Narod ga postavi sebi za poglavara i vojvodu; a Jiftah je ponovio sve svoje uvjete pred Jahvom u Mispi."},{"v":12,"t":"Jiftah posla onda poslanike kralju Amonaca s porukom: “Što ima između tebe i mene da si došao ratovati protiv moje zemlje?”"},{"v":13,"t":"Kralj Amonaca odgovori Jiftahovim poslanicima: “U vrijeme kada je izlazio iz Egipta, Izrael ja zaposjeo moju zemlju od Arnona do Jaboka i Jordana. Zato mi je sada dragovoljno vrati!”"},{"v":14,"t":"Jiftah nanovo pošalje glasnike kralju Amonaca"},{"v":15,"t":"i poruči mu: “Ovako govori Jiftah: Nije Izrael zaposjeo ni moapsku ni amonsku zemlju,"},{"v":16,"t":"nego je, izišavši iz Egipta, Izrael prešao pustinjom do Crvenog mora i došao u Kadeš."},{"v":17,"t":"Tada je poslao Izrael poslanike edomskom kralju s molbom: 'Htio bih proći kroz tvoju zemlju!' Ali ga edomski kralj ne posluša. Poslao ih je i moapskom kralju, ali ni on ne htjede, te Izrael ostade u Kadešu."},{"v":18,"t":"Onda je preko pustinje zaobišao edomsku i moapsku zemlju i došao na istok od moapske zemlje. Narod se utaborio s one strane Arnona ne prelazeći granice Moaba, jer Arnon bijaše moapska međa."},{"v":19,"t":"Izrael posla zatim poslanike Sihonu, amorejskom kralju, koji je vladao u Hešbonu, i poruči mu: 'Pusti nas da prođemo kroz tvoju zemlju do mjesta koje nam je određeno.'"},{"v":20,"t":"Ali Sihon ne dopusti Izraelu da prođe preko njegova područja, nego skupi svu svoju vojsku koja bijaše utaborena u Jahasu i zametnu boj s Izraelom."},{"v":21,"t":"Jahve, Bog Izraelov, predade Sihona i svu njegovu vojsku u ruke Izraelu, koji ih porazi, te Izrael zaposjede svu zemlju Amorejaca koji nastavahu to područje."},{"v":22,"t":"Zaposjeo je tako svu zemlju Amorejaca od Arnona do Jaboka i od pustinje do Jordana."},{"v":23,"t":"I sada kad je Jahve, Bog Izraelov, protjerao Amorejce pred svojim narodom Izraelom, ti bi nas htio odagnati?"},{"v":24,"t":"Zar ne posjeduješ sve što je tvoj bog Kemoš bio oteo starim posjednicima? Tako i sve ono što je Jahve, naš Bog, oteo starim posjednicima, mi sada posjedujemo!"},{"v":25,"t":"Po čemu si ti bolji od moapskog kralja Balaka, sina Siporova? Je li se i on sporio s Izraelom? Je li on ratovao protiv njega?"},{"v":26,"t":"Kada se Izrael nastanio u Hešbonu i u njegovim selima, u Aroeru i u njegovim selima, a tako i po svim gradovima na obali Jordana - evo, već tri stotine godina - zašto ih tada niste oteli?"},{"v":27,"t":"Nisam ja tebi skrivio nego ti meni činiš krivo ratujući protiv mene. Neka Jahve, Sudac, danas presudi između sinova Izraelovih i sinova Amonovih.”"},{"v":28,"t":"Ali kralj Amonaca ne posluša riječi što mu ih je poručio Jiftah."},{"v":29,"t":"Duh Jahvin siđe na Jiftaha te on pođe kroz Gileadovo i Manašeovo pleme, prođe kroz gileadsku Mispu, a od gileadske Mispe dođe iza Amonaca."},{"v":30,"t":"I Jiftah se zavjetova Jahvi: “Ako mi predaš u ruke Amonce,"},{"v":31,"t":"tko prvi iziđe na vrata moje kuće u susret meni kada se budem vraćao kao pobjednik iz boja s Amoncima bit će Jahvin i njega ću prinijeti kao paljenicu.”"},{"v":32,"t":"Jiftah krenu protiv Amonaca da ih napadne i Jahve ih izruči u njegove ruke."},{"v":33,"t":"I porazi ih Jiftah od Aroera do blizu Minita - u dvadeset gradova - i sve do Abel Keramima. Bijaše to njihov veliki poraz; i Amonci bijahu poniženi pred Izraelom."},{"v":34,"t":"Kada se Jiftah vratio kući u Mispu, gle, iziđe mu u susret kći plešući uza zvuke bubnjeva. Bijaše mu ona jedinica, osim nje nije imao ni sina ni kćeri."},{"v":35,"t":"Ugledavši je, razdrije svoje haljine i zakuka: “Jao, kćeri moja, u veliku me tugu bacaš! Zar mi baš ti moraš donijeti nesreću! Zavjetovah se Jahvi i ne mogu zavjeta poreći.”"},{"v":36,"t":"Ona mu odgovori: “Oče moj, ako si učinio zavjet Jahvi, učini sa mnom kako si se zavjetovao, jer ti je Jahve dao da se osvetiš Amoncima, svojim neprijateljima.”"},{"v":37,"t":"Onda zamoli svog oca: “Ispuni mi ovu molbu: pusti me da budem slobodna dva mjeseca; lutat ću po gorama sa svojim drugama i oplakivati svoje djevičanstvo.”"},{"v":38,"t":"“Idi”, reče joj on i pusti je na dva mjeseca. Ona ode sa svojim drugama i oplakivaše na gorama svoje djevičanstvo."},{"v":39,"t":"Kada su prošla dva mjeseca, ona se vrati ocu i on izvrši na njoj zavjet što ga bijaše učinio. I nikada nije upoznala čovjeka. Otada je potekao običaj u Izraelu"},{"v":40,"t":"da svake godine odlaze Izraelove kćeri i oplakuju kćer Jiftaha Gileađanina četiri dana na godinu."}]},"12":{"hr":[{"v":1,"t":"Uto se skupiše ljudi od Efrajimova plemena, prijeđoše Jordan put Safona i rekoše Jiftahu. “Zašto si išao u boj protiv Amonaca a nas nisi pozvao da idemo s tobom? Spalit ćemo ti kuću i tebe!”"},{"v":2,"t":"Jiftah im odgovori: “Imali smo veliku parbu, ja i moj narod, i Amonci su nas teško tlačili. Pozvao sam vas u pomoć, ali me niste izbavili iz njihovih ruku."},{"v":3,"t":"Videći da mi nitko ne pritječe u pomoć, stavih svoj život na kocku, odoh sam na Amonce, i Jahve mi ih predade u ruke. Zašto ste, dakle, pošli danas da ratujete protiv mene?”"},{"v":4,"t":"Tada skupi Jiftah sve Gileađane i udari na Efrajima. Gileađani potukoše Efrajima, jer su ovi govorili: “Vi ste, Gileađani, Efrajimovi bjegunci koji ste živjeli usred Efrajima i Manašea.”"},{"v":5,"t":"Zatim Gileađani presjekoše Efrajimu jordanske gazove, i kada bi koji bjegunac Efrajimov rekao: “Pustite me da prijeđem”, Gileađani bi ga pitali: “Jesi li Efrajimovac?” A kada bi on odgovorio: “Nisam”,"},{"v":6,"t":"oni bi mu kazali: “Hajde reci: Šibolet!” On bi rekao: “Sibolet” jer nije mogao dobro izgovoriti. Oni bi ga tada uhvatili i pogubili na jordanskim plićacima. Tako je poginulo četrdeset i dvije tisuće ljudi iz Efrajimova plemena."},{"v":7,"t":"Jiftah je sudio Izraelu šest godina. A kada je Gileađanin Jiftah umro, pokopaše ga u njegovu gradu, u Gileadu."},{"v":8,"t":"Poslije njega sudac u Izraelu bijaše Ibsan iz Betlehema."},{"v":9,"t":"On je imao trideset sinova i trideset kćeri, koje je poudao iz kuće, a trideset je snaha doveo izvana svojim sinovima. On je sudio Izraelu sedam godina."},{"v":10,"t":"Zatim umrije Ibsan i pokopaše ga u Betlehemu."},{"v":11,"t":"Poslije njega sudac u Izraelu bijaše Elon Zebulunac. On je sudio Izraelu deset godina."},{"v":12,"t":"Zatim umrije Zebulunac Elon i pokopaše ga u Ajalonu u zemlji Zebulunovoj."},{"v":13,"t":"Poslije njega sudac u Izraelu bijaše Abdon, sin Hilela iz Pireatona."},{"v":14,"t":"On je imao četrdeset sinova i trideset unuka koji su jahali na sedamdesetero magaradi. On je sudio Izraelu osam godina."},{"v":15,"t":"Zatim umrije Abdon, sin Hilela iz Pireatona, i pokopaše ga u Pireatonu u Efrajimovoj gori, u zemlji Šaalimu."}]},"13":{"hr":[{"v":1,"t":"Izraelci su opet okrenuli da čine ono što Jahvi nije po volji i Jahve ih predade u ruke Filistejcima za čerdeset godina."},{"v":2,"t":"A bijaše neki čovjek iz Sore, od Danova plemena, po imenu Manoah. Žena mu bila nerotkinja i nije imala djece."},{"v":3,"t":"Toj se ženi ukaza Anđeo Jahvin i reče joj: “Ti si neplodna i nisi rađala."},{"v":4,"t":"Ali se odsad pazi: da ne piješ ni vina ni žestoka pića i da ne jedeš ništa nečisto."},{"v":5,"t":"Jer, zatrudnjet ćeš, evo, i rodit ćeš sina. I neka mu britva ne prijeđe po glavi, jer će od majčine utrobe dijete biti Bogu posvećeno - bit će nazirej Božji i on će početi izbavljati Izraela iz ruke Filistejaca.”"},{"v":6,"t":"Žena ode i kaza mužu: “Božji čovjek došao k meni, lice mu kao u Božjeg anđela, puno dostojanstva. Nisam ga upitala odakle je došao, niti mi on kaza svog imena."},{"v":7,"t":"Ali mi je rekao: 'Ti ćeš začeti i roditi sina. Ne pij odsad ni vina ni žestoka pića i ne jedi ništa nečisto jer će ti dijete biti nazirej Božji od majčine utrobe do smrti.'”"},{"v":8,"t":"Tada se Manoah pomoli Jahvi i reče: “Molim te, Gospode, neka Božji čovjek koga si jednom poslao dođe još jednom k nama i pouči nas što ćemo činiti s djetetom kad se rodi!”"},{"v":9,"t":"Jahve usliši Manoaha i Anđeo Jahvin dođe opet k ženi dok je sjedila u polju. Manoah, muž njezin, ne bijaše kraj nje."},{"v":10,"t":"Žena brzo otrča da obavijesti muža i reče mu: “Gle, ukazao mi se čovjek koji mi je došao onog dana.”"},{"v":11,"t":"Manoah ustade, pođe za ženom i kada dođe k čovjeku, upita ga: “Jesi li ti onaj što je govorio s ovom ženom?” A on odgovori: “Jesam.”"},{"v":12,"t":"“Kada se ispuni ono što si rekao”, opet će Manoah, “po kojim propisima i kako treba postupati s djetetom?”"},{"v":13,"t":"Anđeo Jahvin odgovori Manoahu: “Neka se žena čuva svega što sam joj zabranio."},{"v":14,"t":"Neka ne uživa ništa što dolazi od vinove loze, neka ne pije ni vina ni žestoka pića, neka ne jede ništa nečisto i neka se drži svega što sam joj zapovjedio.”"},{"v":15,"t":"Tada reče Manoah Anđelu Jahvinu: “Rado bismo te ustavili i pogostili jaretom.”"},{"v":16,"t":"Anđeo Jahvin nato će Manoahu: “Sve da me i ustaviš, ja ne bih jeo tvoga jela; nego ako želiš žrtvovati paljenicu, prinesi je Jahvi.” Manoah, ne znajući da je to Anđeo Jahvin,"},{"v":17,"t":"reče tada Anđelu Jahvinu: “Kako ti je ime, da te možemo častiti kada se ispuni što si obećao.”"},{"v":18,"t":"Anđeo Jahvin odgovori mu: “Zašto pitaš za moje ime? Ono je tajanstveno.”"},{"v":19,"t":"Manoah nato uze jare i prinos te ga na stijeni kao paljenicu žrtvova Jahvi koji čini tajanstvene stvari."},{"v":20,"t":"Kada se poče dizati plamen sa žrtvenika k nebu, podiže se Anđeo Jahvin u tome plamenu. Kad to vidješe Manoah i njegova žena, padoše ničice."},{"v":21,"t":"Anđeo Jahvin nije se više ukazivao Manoahu i njegovoj ženi. Manoah tada shvati da je to Anđeo Jahvin."},{"v":22,"t":"“Zacijelo ćemo umrijeti”, reče ženi, “jer smo vidjeli Boga.”"},{"v":23,"t":"“Da nas je htio usmrtiti”, odgovori mu žena, “ne bi iz naše ruke primio paljenice ni prinosa i ne bi nam dao da sve to vidimo niti da takvo što čujemo.”"},{"v":24,"t":"Žena rodi sina i nadjenu mu ime Samson. Dijete odraste i Jahve ga blagoslovi."},{"v":25,"t":"I Jahvin duh bijaše s njim u Danovu taboru, između Sore i Eštaola."}]},"14":{"hr":[{"v":1,"t":"I siđe Samson u Timnu i ugleda ondje djevojku među filistejskim kćerima."},{"v":2,"t":"Vrativši se, povjeri to ocu i majci: “Opazio sam u Timni”, reče on, “djevojku među filistejskim kćerima: oženite me njome.”"},{"v":3,"t":"Otac i mati rekoše: “Zar nema djevojaka među kćerima tvoga plemena i u svemu našem narodu da moraš uzeti ženu između neobrezanih Filistejaca?” Ali Samson odgovori ocu: “Oženi me njome jer mi ona omilje.”"},{"v":4,"t":"Otac mu i majka nisu znali da je to od Jahve, koji je tražio zadjevicu s Filistejcima jer Filistejci u ono doba vladahu Izraelom."},{"v":5,"t":"Samson siđe tako u Timnu i kad dođe do timnjanskih vinograda, gle - odjednom preda nj iskoči mladi lav ričući."},{"v":6,"t":"Duh Jahvin zahvati Samsona, i on goloruk raskida lava kao što se raskida jare; ali ne reče ni ocu ni majci što je učinio."},{"v":7,"t":"Došavši, razgovori se s djevojkom i ona mu omilje."},{"v":8,"t":"Poslije nekog vremena, kada se vratio da je odvede, Samson skrenu da vidi mrtvog lava, a to u mrtvom lavu roj pčela i med."},{"v":9,"t":"On uze meda u ruke i jeo ga je idući putem. Kada se vratio k ocu i majci, dade ga i njima te i oni jedoše; ali im ne reče da ga je uzeo iz mrtvog lava."},{"v":10,"t":"Zatim ode ženi i ondje prirediše gozbu Samsonu; trajala je sedam dana, jer tako običavahu mladi ljudi."},{"v":11,"t":"Ali kako ga se bojahu, izabraše trideset svadbenih drugova da budu uza nj."},{"v":12,"t":"Tad im reče Samson: “Hajde da vam zadam zagonetku. Ako je odgonetnete za sedam svadbenih dana, dat ću vam trideset truba finog platna i trideset svečanih haljina."},{"v":13,"t":"Ali ako je ne mognete odgonetnuti, vi ćete meni dati trideset truba platna i trideset svečanih haljina.” “Zadaj nam zagonetku”, odgovore mu oni, “mi te slušamo.”"},{"v":14,"t":"A on im reče: “Od onog koji jede izišlo je jelo, od jakoga izišlo je slatko.” Ali za tri dana nisu mogli odgonetnuti zagonetke."},{"v":15,"t":"Četvrtoga dana rekoše Samsonovoj ženi: “Izvuci od muža na prijevaru rješenje zagonetke, ili ćemo spaliti i tebe i očev ti dom! Zar ste nas ovamo pozvali da nas oplijenite?”"},{"v":16,"t":"Tada žena, uplakana, obisnu Samsonu oko vrata govoreći: “Ti mene samo mrziš i ne ljubiš me. Zadao si zagonetku sinovima moga naroda, a meni je nisi objasnio.” On joj odgovori: “Nisam je objasnio ni ocu ni majci, a tebi da je kažem?”"},{"v":17,"t":"Ona mu plakaše oko vrata sedam dana, koliko je trajala gozba. Sedmoga dana on joj kaza odgonetku: toliko je na nj navaljivala. I ona je odade sinovima svoga naroda."},{"v":18,"t":"Sedmoga dana, prije nego je zašlo sunce, ljudi iz toga grada rekoše Samsonu: “Što ima slađe od meda i što ima jače od lava?” A on im odgovori: “Da niste s mojom junicom orali, ne biste zagonetke pogodili.”"},{"v":19,"t":"Tada duh Jahvin dođe na njega, te on siđe u Aškelon i ondje pobi trideset ljudi, uze im odjeću i dade svečane haljine onima koji su odgonetnuli zagonetku, a onda se sav gnjevan vrati očevoj kući."},{"v":20,"t":"A Samsonovu ženu dadoše drugu koji mu bijaše svadbeni pratilac."}]},"15":{"hr":[{"v":1,"t":"Poslije nekog vremena, o žetvi pšenice, Samson dođe da pohodi svoju ženu, donijevši joj kozle i reče: “Želim ući k svojoj ženi u ložnicu.” Ali mu tast ne dopusti."},{"v":2,"t":"“Mislio sam,” reče mu on, “da si je zamrzio, pa sam je dao tvome drugu. Ali zar njezina mlađa sestra nije ljepša od nje? Uzmi je namjesto one!”"},{"v":3,"t":"Samson mu odgovori: “Ovaj put neću biti krivac Filistejcima kad im učinim zlo.”"},{"v":4,"t":"I ode Samson, ulovi tri stotine lisica, uze luči i, okrenuvši rep prema repu, stavi jednu luč među dva repa."},{"v":5,"t":"Tad zapali luči, pusti lisice u filistejska polja i popali im snopove, i nepokošeno žito, i vinograde, i maslinike."},{"v":6,"t":"Filistejci zapitaše: “Tko je to učinio?” Odgovoriše im: “Samson, Timnjaninov zet, zato što mu tast oduze ženu i dade je njegovu drugu.” Tad Filistejci odoše i spališe onu ženu i njenu obitelj."},{"v":7,"t":"“Kad ste to učinili”, reče im Samson, “neću mirovati dok vam se ne osvetim.”"},{"v":8,"t":"I sve ih izudara uzduž i poprijeko i žestoko ih porazi. Poslije toga ode u spilju Etamske stijene i ondje se nastani."},{"v":9,"t":"Tad Filistejci krenuše, utaboriše se u Judi i raširiše do Lehija."},{"v":10,"t":"“Zašto ste pošli na nas?” - upitaše ih Judejci. A oni im odgovoriše: “Pošli smo da svežemo Samsona i da mu učinimo kako je on učinio nama.”"},{"v":11,"t":"Tri tisuće Judejaca odoše tada k spilji Etamske stijene i rekoše Samsonu: “Zar ne znaš da Filistejci nama gospodare? Zašto si nam onda to učinio?” On im odgovori: “Kako oni meni, tako ja njima!” A oni mu rekoše:"},{"v":12,"t":"“Dođosmo da te svežemo i predamo u ruke Filistejaca.” “Zakunite mi se”, reče im, “da me nećete ubiti.”"},{"v":13,"t":"“Ne”, odgovoriše mu, “mi ćemo te samo svezati i predati u njihove ruke, ali te zacijelo ne želimo pogubiti.” Onda ga svezaše sa dva nova užeta i odvedoše iz spilje."},{"v":14,"t":"Kad ga dovedoše u Lehi i kad Filistejci, vičući od radosti, pojuriše na nj, duh Jahvin zahvati ga i užeta na njegovim rukama postadoše kao laneni konci, spaljeni ognjem, i spadoše mu s ruku."},{"v":15,"t":"Spazivši još sirovu magareću čeljust, pruži on ruku, uze onu čeljust i pobi njome tisuću ljudi."},{"v":16,"t":"Tad reče Samson: “Magarećom čeljusti gomile prebih, Magarećom čeljusti tisuću pobih.”"},{"v":17,"t":"Rekavši to, baci čeljust iz ruke. Zato odonda ono mjesto zovu Ramat Lehi."},{"v":18,"t":"Kako bijaše jako ožednio, zavapi Jahvi govoreći: “Ti si izvojštio ovu veliku pobjedu rukama svoga sluge, a zar sada moram umrijeti od žeđi i pasti u ruke neobrezanima?”"},{"v":19,"t":"Tad Jahve rasiječe udubinu što je kod Lehija i voda poteče iz nje. Samson se napi i vrati mu se snaga, oživje mu duh. Zato su onom izvoru dali ime En Hakore, a postoji još i danas u Lehiju."},{"v":20,"t":"Samson bijaše sudac u Izraelu za vrijeme filistejske vladavine dvadeset godina."}]},"16":{"hr":[{"v":1,"t":"Odatle ode Samson u Gazu; ondje vidje neku bludnicu i uđe k njoj."},{"v":2,"t":"Žiteljima Gaze javiše: “Samson je došao ovamo!” Opkoliše ga i vrebahu ga svu noć na gradskim vratima. Svu noć bijahu mirni. “Pričekajmo do zore”, mišljahu, “pa ćemo ga ubiti.”"},{"v":3,"t":"Ali je Samson ležao samo do ponoći, a o ponoći ustade, dohvati gradska vrata s oba dovratnika, iščupa ih zajedno s prijevornicom, metnu ih na ramena i odnese na vrh gore koja je nasuprot Hebronu i položi ih ondje."},{"v":4,"t":"Poslije toga zamilova on neku ženu iz doline Soreka po imenu Delilu."},{"v":5,"t":"Filistejski knezovi dođoše k njoj i rekoše joj: “Zavedi ga i doznaj gdje stoji njegova velika snaga, kako bismo ga mogli svladati pa da ga svežemo i učinimo nemoćnim. A dat će ti svaki od nas po tisuću i sto srebrnih šekela.”"},{"v":6,"t":"Delila upita Samsona: “Kaži mi gdje stoji tvoja velika snaga i čime bi se mogao svezati i svladati.”"},{"v":7,"t":"Samson joj odgovori: “Da me svežu sa sedam svježih još neosušenih žila od luka, onemoćao bih i postao kao običan čovjek.”"},{"v":8,"t":"Filistejski knezovi donesu Delili sedam svježih još neosušenih žila i ona ga veza njima."},{"v":9,"t":"Kod nje u sobi bijaše zasjeda i ona viknu: “Samsone, eto Filistejaca na te!” On pokida žile kao što se prekine kučina kad se primakne ognju. I tako ne doznadoše za tajnu njegove snage."},{"v":10,"t":"Tad reče Delila Samsonu: “Prevario si me i slagao mi. Ali mi sada kaži čime bi te trebalo vezati.”"},{"v":11,"t":"On joj odgovori: “Da me dobro svežu novim još neupotrijebljenim užetima, onemoćao bih i postao kao običan čovjek.”"},{"v":12,"t":"Tada Delila uze nova užeta, sveza ga njima i viknu mu: “Samsone, eto Filistejaca na te!” Kod nje u sobi bijaše zasjeda, ali on prekide užeta na rukama kao da su konci."},{"v":13,"t":"Tada Delila reče Samsonu: “Varaš me svejednako i lažeš mi. Kaži mi napokon čime bi te trebalo vezati.” On joj odgovori: “Da otkaš sedam pramenova moje kose na tkalačkom stanu i da ih zaglaviš klinom, onemoćao bih i postao kao običan čovjek.”"},{"v":14,"t":"Ona ga uspava i otka sedam pramenova njegove kose na tkalačkom stanu, zabi klin i viknu mu: “Eto Filistejaca na te, Samsone!” On se probudi i istrgne i klin i tkalački stan. I nije otkrila tajnu njegove snage."},{"v":15,"t":"Delila mu reče: “Kako možeš reći da me ljubiš kad tvoje srce nije sa mnom? Triput si me već prevario i nisi mi kazao gdje je tvoja velika snaga.”"},{"v":16,"t":"Kako mu je svakog dana dodijavala molbama i mučila ga, njemu već dozlogrdje."},{"v":17,"t":"I otvori joj cijelo svoje srce: “Nikada britva nije prešla po mojoj glavi jer sam od majčine utrobe nazirej Božji. Da me obriju, sva bi me snaga ostavila, onemoćao bih i postao bih kao običan čovjek.”"},{"v":18,"t":"Delila tad shvati da joj je otvorio cijelo svoje srce; pozva filistejske knezove i reče im: “Dođite sada jer mi je otvorio cijelo svoje srce.” I filistejski knezovi dođoše k njoj i donesoše sa sobom novac."},{"v":19,"t":"Uspavavši Samsona na svojim koljenima, ona dozva čovjeka te mu obrija s glave sedam pramenova kose. Tako on poče slabiti i ostavi ga snaga."},{"v":20,"t":"Kad ona povika: “Samsone, eto Filistejaca na te!” on se probudi i pomisli: “Izvući ću se kao i uvijek i oslobodit ću se.” Ali nije znao da se Jahve od njega okrenuo."},{"v":21,"t":"Filistejci ga uhvatiše, iskopaše mu oči i odvedoše ga u Gazu. Okovaše ga dvostrukim mjedenim lancem te je okretao mlin u tamnici."},{"v":22,"t":"Ali kosa gdje mu je obrijaše počne opet rasti."},{"v":23,"t":"A knezovi se filistejski skupiše da prinesu veliku žrtvu svome bogu Dagonu i da se provesele. Govorahu oni: “Bog naš predade nam u ruke Samsona, našeg neprijatelja.”"},{"v":24,"t":"A narod, vidjevši ga, uze hvaliti svoga boga i klicati u njegovu čast govoreći: “Bog naš predade nam u ruke Samsona, našeg neprijatelja, koji nam je zemlju pustošio i tolike naše usmrtio.”"},{"v":25,"t":"Kad im se srce razigralo, povikaše: “Dovedite Samsona da nas zabavlja!” I dovedoše iz tamnice Samsona i on igraše pred njima; a onda ga postaviše među stupove."},{"v":26,"t":"Samson tada reče dječaku koji ga je vodio za ruku: “Vodi me i pomozi mi da opipam stupove na kojima počiva zdanje da se naslonim na njih.”"},{"v":27,"t":"A kuća bijaše puna ljudi i žena. Bijahu tu i svi filistejski knezovi, a na krovu tri tisuće ljudi koji su gledali kako Samson igra."},{"v":28,"t":"Samson zavapi Jahvi: “Gospodine Jahve, spomeni me se i samo mi još sada podaj snagu da se Filistejcima odjednom osvetim za oba oka.”"},{"v":29,"t":"I Samson napipa dva srednja stupa na kojima počivaše zdanje, oprije se o njih, desnom o jedan, a lijevom o drugi,"},{"v":30,"t":"i viknu: “Neka poginem s Filistejcima!” Nato uprije iz sve snage i sruši zdanje na knezove i na sav narod koji se ondje nalazio. Više ih ubi umirući nego što ih pobi za života."},{"v":31,"t":"Poslije dođoše njegova braća i sva kuća njegova oca, uzeše ga i odnesoše i pokopaše ga između Sore i Eštaola, u grobu Manoaha, oca njegova. On je sudio Izraelu dvadeset godina."}]},"17":{"hr":[{"v":1,"t":"Bijaše u Efrajimovoj gori čovjek po imenu Mikajehu."},{"v":2,"t":"On reče majci: “Tisuću i sto srebrnih šekela što su ti ukradeni i zbog kojih si izustila kletvu - uši su je moje čule - taj je novac kod mene, ja sam ga uzeo.” Mati mu odgovori: “Jahve te blagoslovio, sine moj!”"},{"v":3,"t":"I Mikajehu vrati joj tisuću i sto srebrnih šekela. A mati mu njegova reče: “Te sam novce posvetila Jahvi iz svoje ruke za tebe, sine moj, da se izdjela za to rezan ili ljeven idol. I evo, za to ih dajem.”"},{"v":4,"t":"Majka uze dvije stotine srebrnih šekela i dade ih zlataru. On načini od njih rezani i ljeveni idol koji postaviše u Mikajehuovoj novoj kući."},{"v":5,"t":"On mu sagradi svetište, zatim načini efod i terafe te posveti jednoga od svojih sinova da mu bude svećenik."},{"v":6,"t":"U to vrijeme u Izraelu nije bilo kralja i svatko je radio po miloj volji."},{"v":7,"t":"Bijaše neki mladić iz Betlehema u Judi, iz Judina plemena; bio je levit i boravio je ondje kao došljak."},{"v":8,"t":"Taj čovjek ode iz grada Betlehema u Judi da se nastani na kakvu prikladnu mjestu kao došljak. Putujući, dođe u Efrajimovu goru do Mikine kuće."},{"v":9,"t":"Mika ga upita: “Odakle dolaziš?” “Ja sam levit iz Judina Betlehema”, odgovori mu on, “i putujem da se negdje nastanim.”"},{"v":10,"t":"“Ostani kod mene”, reče mu Mika, “i budi mi ocem i svećenikom, a ja ću ti davati deset srebrnih šekela na godinu, haljine i hranu.” I levit uđe."},{"v":11,"t":"Levit je pristao da ostane u njega, i mladić mu bijaše kao jedan od sinova."},{"v":12,"t":"Mika posveti levita za svećenika; mladić je postao njegovim svećenikom i živio je u Mikinoj kući."},{"v":13,"t":"“Sad znam”, reče Mika, “da će mi Jahve učiniti dobro kad imam levita za svećenika.”"}]},"18":{"hr":[{"v":1,"t":"U ono vrijeme ne bijaše kralja u Izraelu. Tada je Danovo pleme tražilo zemljište gdje da se naseli, jer mu do toga dana nije dopalo zemljište među Izraelovim plemenima."},{"v":2,"t":"Zato poslaše Danovci petoricu ljudi iz svoga plemena, ljude osobito hrabre iz Sore i Eštaola, da izvide i upoznaju zemlju. I rekoše im: “Idite, istražite zemlju.” I oni dođoše u Efrajimovu goru, do Mikine kuće, i ondje zanoćiše."},{"v":3,"t":"Kako bijahu blizu Mikine kuće, poznaše glas mladog levita; svratiše se onamo te ga upitaše: “Tko te doveo ovamo? Što tu radiš? I što ćeš tu?”"},{"v":4,"t":"A on im odgovori: “Mika je učinio sa mnom tako i tako. On me najmio, a ja mu služim kao svećenik.”"},{"v":5,"t":"“Upitaj Boga”, kazaše mu, “da znamo hoće li nam uspjeti put koji smo poduzeli.”"},{"v":6,"t":"“Idite u miru”, odgovori im svećenik, “put na koji ste pošli po volji je Jahvi.”"},{"v":7,"t":"Tada odoše ona petorica i stigoše u Lajiš. I vidješe da narod koji prebiva u njemu živi bez straha - po običaju Sidonaca - bezbrižno i mirno; imaju svega što rodi zemlja, daleko su od Sidonaca i nemaju nikakvih odnosa s Aramejcima."},{"v":8,"t":"Kad se vratiše svojoj braći u Sori i Eštaolu, braća ih upitaše: “Što ste doznali?”"},{"v":9,"t":"Oni odgovoriše: “Na noge! Navalimo na njih! Zemlja koju smo vidjeli vrlo je dobra. O vi, lijenčine! Ne oklijevajte navaliti da osvojite tu zemlju."},{"v":10,"t":"Kada dođete, naći ćete ondje bezbrižan narod. Zemlja je prostrana. Bog je predao u vaše ruke mjesto koje ne oskudijeva ni u čemu što rodi zemlja!”"},{"v":11,"t":"Tako je odande krenulo šest stotina naoružanih ljudi iz Danova plemena iz Sore i Eštaola."},{"v":12,"t":"Krenuli su i utaborili se u Kirjat Jearimu u Judi. Zato se to mjesto naziva do današnjeg dana Danovim taborom, a nalazi se na zapadu od Kirjat Jearima."},{"v":13,"t":"Odatle se zaputiše u Efrajimovu goru i dođoše do Mikine kuće."},{"v":14,"t":"A ona petorica što bijahu išla izviđati zemlju rekoše svojoj braći: “Znate li da u ovim kućama imaju efod, terafe i ljeveni idol? Sada pazite što ćete raditi.”"},{"v":15,"t":"Skrenuvši, oni uđoše u kuću mladog levita, u Mikinu kuću, i pozdraviše ga."},{"v":16,"t":"I dok je šest stotina naoružanih ljudi od Danovih sinova stajalo pred vratima,"},{"v":17,"t":"ona petorica što su išla izviđati zemlju uđoše, uzeše efod, terafe i ljeveni idol, a svećenik stajaše na pragu pokraj šest stotina naoružanih ljudi."},{"v":18,"t":"Kad su ušli u Mikinu kuću i uzeli efod, terafe, rezani i ljeveni idol, svećenik im reče: “Što to radite?”"},{"v":19,"t":"“Šuti”, odgovoriše mu. “Stavi ruku na usta i hajde s nama. Bit ćeš nam otac i svećenik. Zar ti je bolje biti svećenikom u kući jednog čovjeka nego da budeš svećenikom jednog plemena i roda u Izraelu?”"},{"v":20,"t":"Svećenik se obradova; uze on efod, terafe i rezani i ljeveni idol te ode s ljudima."},{"v":21,"t":"Vrativši se na put kojim su krenuli, odoše pustivši naprijed žene i djecu, stoku i dragocjenosti."},{"v":22,"t":"Bijahu već daleko od Mikine kuće, kad gle - ljudi što življahu u susjednim kućama, blizu Mikine, uzbunili se i krenuli u potjeru za Danovcima."},{"v":23,"t":"Kada počeše vikati za Danovim sinovima, oni se obazreše i rekoše Miki: “Što ti je? Što ste se skupili?”"},{"v":24,"t":"On odgovori: “Uzeli ste moga boga koga sam sebi načinio i svećenika te odlazite. A što ostaje meni? I još mi kažete: 'Što ti je?'”"},{"v":25,"t":"Danovci mu odgovore: “Da te više nismo čuli! Jer bi gnjevni ljudi mogli udariti na vas te bi upropastio sebe i svoju kuću!”"},{"v":26,"t":"Danovci odoše dalje, a Mika, videći da su jači od njega, okrenu se i vrati kući."},{"v":27,"t":"I tako, uzevši boga što ga je načinio Mika i svećenika koga je najmio da mu služi, Danovci navališe na Lajiš, na mirne i spokojne ljude, te ih posjekoše oštrim mačem i spališe grad."},{"v":28,"t":"Nikoga ne bijaše da pomogne Lajišanima, jer bijahu daleko od Sidona i ne imahu nikakvih odnosa s Aramejcima, a osim toga grad bijaše u dolini koja se pruža prema Bet-Rehobu. Potom su opet sagradili grad i nastanili se u njemu."},{"v":29,"t":"I nazvaše ga Dan, po imenu svoga pretka Dana, koji se rodio Izraelu. A prije se grad zvao Lajiš."},{"v":30,"t":"I Danovci namjestiše sebi rezani i ljeveni idol. A Jonatan, sin Geršona, sina Mojsijeva, a zatim njegovi sinovi, bijahu svećenici Danova plemena do dana kada je narod bio odveden u izgnanstvo."},{"v":31,"t":"I stajaše im onaj rezani i ljeveni idol što ga je Mika načinio, i ostade ondje za sve vrijeme dokle Dom Božji bijaše u Šilu."}]},"19":{"hr":[{"v":1,"t":"U ono vrijeme kad u Izraelu još ne bijaše kralja, živio neki čovjek, levit, kao došljak na kraju Efrajimove gore. Uzeo on za inoču ženu iz Judina Betlehema."},{"v":2,"t":"Rasrdivši se jednom, njegova ga inoča ostavi i vrati se u očevu kuću u Judin Betlehem i bila je ondje neko vrijeme, kakva četiri mjeseca."},{"v":3,"t":"Njen muž ode k njoj da je urazumi i dovede natrag; imao je sa sobom slugu i dva magarca. Dok je prilazio kući oca mlade žene, opazi ga tast i veselo mu iziđe u susret."},{"v":4,"t":"Tast, otac mlade žene, zadrži ga tri dana kod sebe te su jeli, pili i noćivali."},{"v":5,"t":"Četvrtoga dana uraniše; levit se spremao da ide, kad otac mlade žene reče zetu: “Okrijepi se zalogajem kruha, pa onda idite.”"},{"v":6,"t":"I tako sjedoše te su obojica jela i pila, a onda otac mlade žene reče čovjeku: “Hajde, ostani još noćas i proveseli se!”"},{"v":7,"t":"A kad čovjek ustade da pođe, tast uze navaljivati na njega te on još jednom ondje prenoći."},{"v":8,"t":"Petoga dana levit urani da krene, ali mu otac mlade žene reče: “Okrijepi se najprije!” Tako su proveli vrijeme jedući zajedno dok se nije nagnuo dan."},{"v":9,"t":"Muž ustade da ide, s inočom i slugom, kad mu tast, otac mlade žene, reče: “Evo se dan nagnuo k večeru. Prenoći još ovdje i proveseli se, pa sutra uranite na put i vratite se svom šatoru.”"},{"v":10,"t":"Ali čovjek ne htjede prenoćiti nego ustade i krenu. Tako je došao do pred Jebus, to jest Jeruzalem. S njim su bila dva osamarena magarca, inoča i sluga."},{"v":11,"t":"Kad su bili blizu Jeruzalema, dan se već jako nagnuo, pa sluga reče svome gospodaru: “Hajde da se svratimo u taj jebusejski grad da tu prenoćimo.”"},{"v":12,"t":"Ali mu gospodar odgovori: “Nećemo se svraćati u grad tuđinaca koji nisu Izraelci, nego ćemo ići do Gibee.”"},{"v":13,"t":"Još reče sluzi: “Hajde, požurimo se da stignemo u koje od tih mjesta gdje ćemo prenoćiti, u Gibeu ili Ramu.”"},{"v":14,"t":"I prođoše, nastavljajući put. Kad su stigli pred Benjaminovu Gibeu, sunce je zapadalo."},{"v":15,"t":"Oni skrenuše onamo da prenoće u Gibei. Ušavši, levit sjede na gradskom trgu, ali ne bijaše nikoga da ih primi u kuću da prenoće."},{"v":16,"t":"I dođe neki starac koji se predvečer vraćao s posla u polju. Bijaše to čovjek iz Efrajimove gore; življaše u Gibei kao došljak, a svi žitelji toga mjesta bijahu Benjaminovci."},{"v":17,"t":"Podigavši oči, ugleda putnika na gradskom trgu: “Odakle dolaziš i kamo ćeš?” - upita ga starac."},{"v":18,"t":"A on mu odgovori: “Idemo od Judina Betlehema, na kraj Efrajimove gore. Ja sam odande. Išao sam u Judin Betlehem i vraćam se kući, ali nema nikoga da me primi k sebi u kuću."},{"v":19,"t":"Imam i slame i krme za svoje magarce, a i kruha i vina za sebe, za svoju ženu i za momka koji prati mene, tvoga slugu. Imamo svega dosta.”"},{"v":20,"t":"“Mir s tobom i dobro mi došao”, odgovori starac. “Moja je briga što ti je potrebno, samo nemoj noćiti na trgu.”"},{"v":21,"t":"I uvede ga u svoju kuću i baci krme magarcima. Putnici su oprali noge, a onda jeli i pili."},{"v":22,"t":"Dok su se oni krijepili, gle, neki građani, opaki ljudi, okružiše kuću i, lupajući svom snagom o vrata, rekoše starcu, gospodaru kuće: “Izvedi toga čovjeka što je ušao u tvoju kuću da ga se namilujemo.”"},{"v":23,"t":"Tad iziđe domaćin iz kuće i reče im: “Ne, braćo moja, ne činite zla. Taj je čovjek ušao u moju kuću, zato ne činite bezakonja."},{"v":24,"t":"Evo, moja je kći djevica, prepustit ću vam je. Činite od nje što vam drago, ali ovom čovjeku ne činite bezakonja.”"},{"v":25,"t":"Ljudi ga ne htjedoše poslušati. Tad onaj čovjek uze inoču te im je izvede. Oni su je silovali i zlostavljali svu noć do jutra, a kad je zora zabijeljela, pustiše je."},{"v":26,"t":"Pred zoru žena dođe i pade na ulaz kuće onog čovjeka gdje je bio njen gospodar i ležala je ondje dok se nije razdanilo."},{"v":27,"t":"Njen je gospodar ujutro ustao, otvorio kućna vrata te izišao da nastavi put, kad spazi ženu, svoju inoču, kako leži na kućnim vratima s rukama na pragu."},{"v":28,"t":"“Ustani, idemo!” - reče joj. Ali ne bijaše odgovora. Onda je uze, natovari na magarca i krenu na put da se vrati kući."},{"v":29,"t":"Kada je došao kući, trže nož i uze mrtvo tijelo inočino, rasiječe ga, ud po ud, na dvanaest dijelova te ih razasla u sve krajeve Izraela."},{"v":30,"t":"I tko god vidje reče: “Ovakvo što se nije dogodilo od dana kada su Izraelci izašli iz Egipta do današnjeg dana. Valja o tome promisliti, vijećati i govoriti.”"}]},"20":{"hr":[{"v":1,"t":"Tada iziđe sav Izrael i sabra se sva zajednica kao jedan čovjek, od Dana do Beer Šebe i do gileadske zemlje, kod Jahve u Mispi."},{"v":2,"t":"Glavari svega naroda, svih Izraelovih plemena, dođoše na zbor Božjeg naroda, četiri stotine tisuća pješaka vičnih maču."},{"v":3,"t":"A Benjaminovci doznaše da su Izraelovi sinovi uzišli u Mispu. Sinovi Izraelovi zapitaše tada: “Kažite nam kako se dogodio zločin!”"},{"v":4,"t":"Levit, muž ubijene žene, uze riječ: “Došao sam s inočom u Benjaminovu Gibeu da prenoćim."},{"v":5,"t":"A građani Gibee ustadoše na mene i noću opkoliše kuću u kojoj sam bio; mene su htjeli ubiti, a moju su inoču silovali tako da je umrla."},{"v":6,"t":"Zato sam uzeo mrtvu inoču, rasjekao je u komade i razaslao je u sve krajeve Izraelove baštine, jer su počinili sramotno djelo u Izraelu."},{"v":7,"t":"Izraelci, evo vas svih ovdje. Posavjetujte se i ovdje stvorite odluku.”"},{"v":8,"t":"Sav narod ustade kao jedan čovjek govoreći: “Neka se nitko od nas ne vraća svome šatoru, neka nitko ne ide svojoj kući!"},{"v":9,"t":"Nego da sada ovo učinimo Gibei: bacit ćemo ždrijeb;"},{"v":10,"t":"i uzet ćemo iz svih Izraelovih plemena po deset ljudi od stotine, po stotinu od tisuće i po tisuću od deset tisuća: oni će nositi hranu vojsci, onima koji će krenuti da kazne Benjaminovu Gibeu za sramotu što ju je počinila u Izraelu.”"},{"v":11,"t":"I sabraše se svi Izraelci protiv onoga grada, udruženi kao jedan čovjek."},{"v":12,"t":"Tada Izraelova plemena razaslaše poslanike po svemu Benjaminovu plemenu s porukom: “Kakav se to zločin dogodio među vama?"},{"v":13,"t":"Sada izručite one opake ljude što su u Gibei da ih smaknemo te iskorijenimo zlo iz Izraela!” Ali Benjaminovci ne htjedoše poslušati svoje braće Izraelaca."},{"v":14,"t":"Benjaminovci se skupiše u Gibeu iz svojih gradova da se pobiju s Izraelcima."},{"v":15,"t":"A Benjaminovaca koji su došli iz raznih gradova nabrojiše toga dana dvadeset i šest tisuća ljudi vičnih maču, bez stanovnika Gibee."},{"v":16,"t":"Od svega toga naroda bijaše sedam stotina vrsnih ljudi, koji su bili ljevaci, i svaki je taj gađao kamenom iz praćke navlas točno, ne promašujući cilja."},{"v":17,"t":"A bijaše Izraelaca, osim sinova Benjaminovih, četiri stotine tisuća, sve ljudi vičnih maču i sve samih ratnika."},{"v":18,"t":"I sinovi Izraelovi, ustavši, pođoše u Betel da se posavjetuju s Bogom: “Tko će od nas prvi u boj protiv Benjaminovaca?” - zapitaše Izraelci. A Jahve odgovori: “Neka Juda pođe prvi.”"},{"v":19,"t":"Izjutra krenuše Izraelci te se utaboriše pred Gibeom."},{"v":20,"t":"Krenuvši u boj protiv Benjaminovaca, svrstaše se u bojni red pred Gibeom."},{"v":21,"t":"A Benjaminovci iziđoše iz Gibee i pobiše toga dana Izraelu dvadeset i dvije tisuće ljudi, koji ostadoše na onome polju."},{"v":22,"t":"Izraelci odoše i plakahu pred Jahvom sve do večeri, a onda upitaše Jahvu govoreći: “Moramo li opet izići u boj protiv sinova svoga brata Benjamina?” A Jahve im odgovori: “Pođite na njega!”"},{"v":23,"t":"Tada se vojska Izraelovih sinova ohrabri i nanovo svrsta u bojni red na istome mjestu gdje se svrstala prvog dana."},{"v":24,"t":"Drugoga se dana Izraelci približiše Benjaminovcima,"},{"v":25,"t":"ali toga drugog dana Benjamin iziđe iz Gibee pred njih i pobi Izraelcima još osamnaest tisuće ljudi, koji ostadoše na onome polju - sve sami poizbor ratnici, vični maču."},{"v":26,"t":"Tada svi Izraelci i sav narod odoše u Betel te plakahu i stajahu ondje pred Jahvom; cio su dan postili do večeri, prinosili paljenice i žrtve pomirnice pred Jahvom."},{"v":27,"t":"I tad opet Izraelci upitaše Jahvu, jer se u ono vrijeme Kovčeg saveza Božjega nalazio na tome mjestu,"},{"v":28,"t":"i Pinhas, sin Aronova sina Eleazara, posluživaše ga. Oni upitaše: “Moramo li opet izići u boj protiv sinova našega brata Benjamina?” A Jahve im odgovori: “Pođite, jer ću ih sutra predati u vaše ruke.”"},{"v":29,"t":"Tad Izrael postavi čete u zasjedu oko Gibee."},{"v":30,"t":"Trećega dana pođoše Izraelci protiv Benjaminovaca i svrstaše se u bojne redove pred Gibeom, kao i prije."},{"v":31,"t":"Benjaminovci iziđoše na njih, a oni ih odmamiše daleko od grada. Kao i prije, ubijahu Benjaminovci neke po putovima, od kojih jedan ide u Betel, a drugi u Gibeu; ubiše tako oko trideset Izraelaca."},{"v":32,"t":"I govorahu Benjaminovci: “Evo ih tučemo kao i prvi put.” A Izraelci rekoše: “Bježimo dok ih ne odmamimo na otvorene putove, daleko od grada!”"},{"v":33,"t":"Tada se glavnina Izraelove vojske pomakne sa svoga položaja i svrsta se u bojni red kod Baal Tamara, a zasjeda Izraelova iziđe iz svog skrovišta zapadno od Gibee."},{"v":34,"t":"Deset tisuća vrsnih ljudi izabranih iz sveg Izraela sleže se prema Gibei. Boj bijaše žestok. Benjaminovci nisu ni slutili da će ih zadesiti zlo."},{"v":35,"t":"I Jahve potuče Benjamina pred Izraelom toga dana te Izraelci pobiše Benjaminu dvadeset i pet tisuća i sto ljudi vičnih maču."},{"v":36,"t":"Benjaminovci vidješe da su pobijeđeni. Ljudi Izraelci bijahu se povukli sa svojih bojnih položaja pred Benjaminom uzdajući se u zasjedu što su je postavili oko Gibee."},{"v":37,"t":"A oni koji bijahu u zasjedi navališe brže na Gibeu i, ušavši u nju, posjekoše oštrim mačem sve stanovništvo."},{"v":38,"t":"Izraelovi se ljudi bijahu dogovorili s onima u zasjedi da ovi podignu iz grada stup dima kao znak:"},{"v":39,"t":"tada bi se Izraelovi ljudi povukli iz boja. Benjamin poče ubijati Izraelce i posiječe im tridesetak ljudi. “Doista, padaju pred nama kao u prijašnjem boju.”"},{"v":40,"t":"A kada se znak, stup dima, počeo dizati iz grada, obazre se Benjamin i vidje kako se plamen iz svega grada diže prema nebu."},{"v":41,"t":"Tada se Izraelovi ljudi okrenuše, a Benjaminovce obuze užas jer vidješe da ih je zadesilo zlo."},{"v":42,"t":"I pobjegoše ispred Izraelaca prema pustinji, ali im ratnici bijahu za petama, a oni što su dolazili iz grada ubijahu ih s leđa."},{"v":43,"t":"Tako su opkolili Benjamina i, goneći ga bez predaha, uništiše ga pred Gibeom na istočnoj strani."},{"v":44,"t":"I palo je Benjaminu osmnaest tisuća ljudi, sve samih vrsnih junaka."},{"v":45,"t":"Preživjeli se okrenuše i pobjegoše u pustinju prema Rimonskoj stijeni. Sijekući po cestama, Izraelci pobiše još pet tisuća ljudi; a onda pognaše Benjamina do Gideoma i pobiše još dvije tisuće ljudi."},{"v":46,"t":"Toga dana palo je Benjaminovaca dvadeset tisuća ljudi vičnih maču, sve samih vrsnih junaka."},{"v":47,"t":"Šest stotina ljudi pobjeglo je u pustinju prema Rimonskoj stijeni."},{"v":48,"t":"Izraelovi se ljudi vratiše potom Benjaminovcima, posjekoše oštrim mačem muškarce u gradovima, stoku i što se god našlo; i sve gradove na koje su naišli u Benjaminu popališe ognjem."}]},"21":{"hr":[{"v":1,"t":"Izraelovi se ljudi bijahu ovako zakleli u Mispi: “Nitko od nas neće dati svoju kćer za ženu Benjaminovu sinu.”"},{"v":2,"t":"I ode narod u Betel i ostade ondje pred Bogom do večeri, naričući i jecajući."},{"v":3,"t":"Govorili su: “Zašto se, o Jahve, Bože Izraelov, ova nesreća morala dogoditi da Izraelu danas nestane jednog plemena?”"},{"v":4,"t":"Sutradan uraniše ljudi i sagradiše ondje žrtvenik; prinesoše paljenice i žrtve zahvalnice."},{"v":5,"t":"Tad zapitaše Izraelci: “Ima li koga među svim plemenima Izraelovim da nije došao na zbor Jahvi?” Jer su se svečano zakleli da će pogubiti onoga tko ne dođe u Mispu k Jahvi."},{"v":6,"t":"Izraelcima se sada sažalilo na brata Benjamina te rekoše: “Danas je otkinuto jedno pleme od Izraela."},{"v":7,"t":"Kako ćemo dati žene onima koji su preostali kad se zaklesmo Jahvom da im nećemo dati svojih kćeri za žene?”"},{"v":8,"t":"Zato zapitaše: “Ima li koga među Izraelovim plemenima da nije došao k Jahvi u Mispu?” I pronađe se da nije došao u tabor, na zbor, nitko od žitelja Jabeša u Gileadu."},{"v":9,"t":"Jer kada se narod prebrojio, ondje ne bijaše nikoga od žitelja Jabeša u Gileadu."},{"v":10,"t":"Zato zajednica posla onamo dvanaest tisuća hrabrih ljudi i zapovjedi im: “Idite i posijecite oštrim mačem stanovnike Jabeša u Gileadu, zajedno sa ženama i djecom."},{"v":11,"t":"Evo što ćete učiniti: izručit ćete prokletstvu sve muškarce i sve žene što su dijelile postelju sa čovjekom, ali ćete sačuvati život djevicama.” Tako i učiniše."},{"v":12,"t":"I našli su među stanovnicima Jabeša u Gileadu četiri stotine mladih djevojaka koje nisu dijelile postelje s čovjekom i doveli su ih u tabor u Šilu, koji je u Kanaanu."},{"v":13,"t":"Sva zajednica posla tada poslanike Benjaminovcima koji bijahu na Rimonskoj stijeni: objaviše im mir."},{"v":14,"t":"Tako se oporavi Benjamin. Dadoše im one među ženama iz Jabeša u Gileadu koje su ostavili na životu, ali ih ne bijaše dovoljno za sve."},{"v":15,"t":"Narodu se sažalio Benjamin što je Jahve načinio prazninu među Izraelovim plemenima."},{"v":16,"t":"“Kako ćemo naći žene onima što su ostali”, rekoše starješine zbora, “kad su Benjaminu istrijebljene žene?”"},{"v":17,"t":"Rekoše još: “Kako sačuvati ostatak Benjaminu da se ne zatre jedno pleme iz Izraela?"},{"v":18,"t":"A ne možemo im dati svoje kćeri za žene.” Jer se bijahu zakleli rekavši: “Proklet bio onaj koji dade ženu Benjaminu!”"},{"v":19,"t":"“Ali”, rekoše, “svake se godine slavi u Šilu Jahvina svetkovina.” Grad se nalazi na sjeveru od Betela, istočno od ceste koja vodi iz Betela u Šekem i južno od Lebone."},{"v":20,"t":"I zato svjetovaše Benjaminovce: “Idite u zasjedu po vinogradima."},{"v":21,"t":"Pazite, pa kada djevojke iz Šila iziđu da plešu u kolu, vi iskočite iz vinograda, otmite svaki sebi ženu između šilskih kćeri pa otiđite u Benjaminovu zemlju."},{"v":22,"t":"A kad njihovi očevi ili njihova braća dođu da se prituže na vas, mi ćemo im reći: 'Oprostite im što je svaki uzeo po ženu kao u ratu; vi im ih niste dali, pa je tako krivnja na vama.'”"},{"v":23,"t":"Benjaminovci učiniše tako i od djevojaka koje oteše uzeše onoliki broj žena koliko bijaše njih. Onda odoše svaki na svoju baštinu, sagradiše opet gradove i naseliše se u njima."},{"v":24,"t":"Izraelci se tada raziđoše, svaki u svoje pleme i u svoj rod, i svaki se odande vrati na svoju baštinu."},{"v":25,"t":"U to vrijeme ne bijaše kralja u Izraelu i svatko je živio kako mu se činilo da je pravo."}]}},"RUT":{"1":{"hr":[{"v":1,"t":"U ono vrijeme kada su vladali suci nastala glad u zemlji, pa iz Betlehema Judina jedan čovjek ode sa svojom ženom i sa svoja dva sina da se naseli na Moapskim poljanama."},{"v":2,"t":"Taj se čovjek zvao Elimelek, žena mu Noemi, a dva njegova sina: Mahlon i Kiljon; svi bijahu Efraćani iz Betlehema Judina. Stigoše na Moapske poljane i tu se nastaniše."},{"v":3,"t":"Tada Elimelek, Noemin muž, umrije, i ona osta sama sa svoja dva sina."},{"v":4,"t":"Oni se oženiše Moapkama; jedna se zvala Orpa, a druga Ruta. I tu proboraviše deset godina."},{"v":5,"t":"Onda umriješe i Mahlon i Kiljon, i tako Noemi osta i bez svoja dva sina i bez svoga muža."},{"v":6,"t":"Tada se ona diže sa svojim snahama da ode s Moapskih poljana jer je čula na Moapskim poljanama da je Jahve pohodio narod svoj i dao mu kruha."},{"v":7,"t":"Ode, dakle, ona iz mjesta gdje je živjela, a s njome i njezine snahe; krenuše na put da se vrate u zemlju Judinu."},{"v":8,"t":"Noemi tada reče svojim dvjema snahama: “Vratite se svaka domu majke svoje! Neka vam Jahve bude milostiv kao što vi bijaste pokojnicima i meni."},{"v":9,"t":"Neka vam Jahve udijeli da obje nađete mir, svaka u domu svoga muža!” I poljubi ih, a one briznuše u plač."},{"v":10,"t":"I rekoše joj: “Ne! Mi ćemo s tobom, tvome narodu.”"},{"v":11,"t":"Ali im reče Noemi: “Vratite se natrag, kćeri moje! Zašto biste išle sa mnom? Zar ću još imati sinova u utrobi svojoj da vam budu muževi?"},{"v":12,"t":"Vratite se natrag, kćeri moje, idite samo! Odviše sam stara, nisam za udaju. Pa i kad bih rekla: 'Imam nade da se udam još noćas i da rodim sinove' -"},{"v":13,"t":"zar biste mogle čekati da odrastu i zar biste radi njih ostale neudate? Ne, kćeri moje, tuga bi moja bila veća od vaše, jer se ruka Jahvina digla na me.”"},{"v":14,"t":"One i opet zaplakaše i zajecaše. Orpa poljubi svoju svekrvu i vrati se, a Ruta ostade s njom."},{"v":15,"t":"Noemi joj reče: “Eto vidiš, jetrva se tvoja vratila narodu svome i bogu svome: vrati se i ti za jetrvom svojom!”"},{"v":16,"t":"A Ruta joj odgovori: “Nemoj me tjerati da te ostavim i da odem od tebe: jer kamo ti ideš, idem i ja i gdje se ti nastaniš, nastanit ću se i ja; tvoj narod moj je narod i tvoj Bog moj je Bog."},{"v":17,"t":"Gdje ti umreš, umrijet ću i ja, gdje tebe pokopaju, pokopat će i mene. Neka mi Jahve uzvrati svakim zlom i nevoljom ako me što drugo, osim smrti, rastavi od tebe.”"},{"v":18,"t":"Videći gdje je tvrdo naumila da ide s njom, prestade je odvraćati."},{"v":19,"t":"Tako su zajedno išle dok ne dođoše u Betlehem. A kad dođoše u Betlehem, sav se grad uzbudi zbog njih. “Ma je li ovo Noemi?” - pitahu žene."},{"v":20,"t":"A ona im odgovaraše: “Ne zovite me više Noemi nego me zovite Mara; jer me Šadaj gorčinom ispunio!"},{"v":21,"t":"Odavde sam otišla punih ruku, a sad me Jahve vraća bez igdje ičega. Zašto me zovete Noemi kad Jahve posvjedoči protiv mene i Svemogući me u tugu zavi?”"},{"v":22,"t":"Tako se vrati Noemi s Rutom Moapkom, snahom svojom, s Moapskih poljana. Stigle su u Betlehem baš kad je počela žetva ječma."}]},"2":{"hr":[{"v":1,"t":"Noemi imaše rođaka po mužu, čovjeka vrlo imućna, iz porodice Elimelekove: zvao se Boaz."},{"v":2,"t":"Tada Ruta Moapka reče Noemi: “Htjela bih ići u polje pabirčiti klasje za onim u koga nađem milost.” Ona joj odgovori: “Hajde, kćeri moja!”"},{"v":3,"t":"I ode, dođe u polje te poče pabirčiti za žeteocima. A sreća je dovede u polje koje pripadaše Boazu, iz roda Elimelekova."},{"v":4,"t":"I gle, dođe Boaz iz Betlehema. “Jahve bio s vama!” - pozdravi on žeteoce. A oni mu odgovoriše: “Jahve te blagoslovio!”"},{"v":5,"t":"Boaz će nato momku koji je nadzirao žeteoce: “Čija je ona mlada žena?”"},{"v":6,"t":"A momak koji bijaše nad žeteocima odgovori: “Ono je mlada Moapka što je došla prateći Noemi s Moapskih poljana."},{"v":7,"t":"Pitala je: 'Smijem li pabirčiti i kupiti klasje između snopova za žeteocima?' I došla je, eto, i ostala od ranog jutra sve dosad; i samo je malo ušla u kuću.”"},{"v":8,"t":"Onda Boaz reče Ruti: “Čuj me, kćeri moja, ne idi pabirčiti u drugoga nego se drži mojih njiva i mojih poslenika."},{"v":9,"t":"Pazi na kojoj njivi oni žanju, pa idi za njima. A naredio sam momcima da te nitko ne dira. Kad ožedniš, idi k posudama i pij što moje sluge zahitaju.”"},{"v":10,"t":"Ona tada pade ničice, pokloni se do zemlje i reče: “Čime sam stekla toliku milost u očima tvojim da mi posvećuješ pažnju kad sam tuđinka?”"},{"v":11,"t":"Boaz joj odgovori: “Čuo sam što si sve učinila za svoju svekrvu poslije smrti svoga muža; kako si ostavila oca svoga, majku svoju i zavičaj svoj te došla u narod kojega do jučer ili prekjučer nisi poznavala."},{"v":12,"t":"Neka ti Jahve plati sve što si učinila i neka ti udijeli pravu nagradu Jahve, Bog Izraelov, kad si došla da se pod krila njegova skloniš!”"},{"v":13,"t":"Ona preuze: “Kad bih mogla uvijek nalaziti milost u tvojim očima, gospodaru, jer si me utješio i milostivo progovorio sluškinji svojoj, ako i nisam kao jedna od tvojih sluškinja.”"},{"v":14,"t":"Kad bijaše vrijeme ručku, Boaz joj reče: “Hodi ovamo, jedi ovog kruha i umoči svoj zalogaj u ocat!” Ona sjede pokraj žetelaca, a on stavi pred nju prženih zrna. Jela je i nasitila se i još joj preteče."},{"v":15,"t":"Kad je ustala da pabirči dalje, Boaz zapovjedi svojim slugama: “I među snopljem neka ona pabirči, a vi joj nemojte zanovijetati."},{"v":16,"t":"Nego navlaš ispuštajte klasove iz svojih rukoveti i ostavljajte joj neka kÓupi i nemojte je koriti!”"},{"v":17,"t":"I tako je pabirčila sve do večeri, pa onda ovrše ono što je napabirčila: bijaše otprilike jedna efa ječma."},{"v":18,"t":"Uze ona svoje i dođe u grad, a svekrva vidje koliko je napabirčila. Tada Ruta izvadi i dade joj što joj bijaše preteklo pošto se nasitila."},{"v":19,"t":"Svekrva je upita: “Gdje si pabirčila danas? Gdje si radila? Neka je blagoslovljen onaj koji je pogledao na te!” Onda ona pripovjedi svekrvi kod koga je radila i reče: “Čovjek u koga sam danas radila zove se Boaz.”"},{"v":20,"t":"Tada će Noemi svojoj snasi: “Neka Jahve blagoslovi onoga koji ne uskraćuje dobrote svoje ni živima ni mrtvima!” I dometnu Noemi: “Taj je čovjek naš rod; jedan od naših skrbnika.”"},{"v":21,"t":"Ruta Moapka pripovjedi dalje: “Još mi reče: 'Drži se mojih poslenika dokle ne požanju sve moje!'”"},{"v":22,"t":"Noemi nato reče Ruti, snasi svojoj: “Dobro je, kćeri moja, idi za njegovim poslenicima da ti ne bude neprilike na kojoj drugoj njivi.”"},{"v":23,"t":"I tako se držala poslenika Boazovih i pabirčila dokle ne požeše i ječam i pšenicu. I živjela je kod svekrve svoje."}]},"3":{"hr":[{"v":1,"t":"Onda će joj Noemi, svekrva njezina: “Kćeri moja, da ti potražim mirno mjesto gdje bi mogla biti sretna?"},{"v":2,"t":"Vidiš, Boaz, s čijim si se poslenicima našla, naš je rođak. Evo, on će noćas vijati ječam na gumnu."},{"v":3,"t":"Umij se ti i namaži, lijepo se odjeni pa idi na gumno. Ne daj da te prepozna prije nego što se najede i napije."},{"v":4,"t":"Kad bude lijegao, dobro pazi gdje će leći; pa kad legne, otiđi onamo, podigni mu pokrivač s nogu i lezi ondje! Tada će ti on reći što ti je činiti.”"},{"v":5,"t":"Ona joj odgovori: “Učinit ću sve kako mi kažeš.”"},{"v":6,"t":"I siđe na gumno i učini sve kako joj je svekrva naredila."},{"v":7,"t":"A Boaz, pošto je jeo i pio i tako se odobrovoljio, ode i leže kraj stoga. Onda ona priđe polako, otkri mu noge i leže."},{"v":8,"t":"Kad bijaše oko ponoći, trže se čovjek i obrnu se, i gle: žena leži do njegovih nogu."},{"v":9,"t":"“Tko si?” - upita on, a ona odgovori: “Ja sam Ruta, sluškinja tvoja. Raširi skut svoje haljine na sluškinju svoju jer si mi skrbnik.”"},{"v":10,"t":"“Blagoslovio te Jahve, kćeri moja!” - dočeka on. “Ovaj drugi tvoj čin milosti još je vredniji od prvoga, jer se nisi trudila da slijediš mlade poslenike, bili oni bogati ili siromašni."},{"v":11,"t":"I zato se, kćeri moja, sada ne plaši: učinit ću ti sve što zatražiš, jer sva vrata moga naroda znaju da si čestita žena."},{"v":12,"t":"Jest, uistinu sam ti skrbnik; ali postoji još bliži od mene."},{"v":13,"t":"Ostani noćas; ako te sutra ujutro on kao skrbnik htjedne uzeti, dobro, neka te uzme; a ne htjedne li, uzet ću te ja, tako mi Jahve! Spavaj do jutra.”"},{"v":14,"t":"I spavaše ona do njegovih nogu do jutra. On ustade prije nego što mogaše čovjek čovjeka razaznati jer mišljaše: “Ne treba da znaju da je žena bila na gumnu.”"},{"v":15,"t":"I kaza joj: “Daj ogrtač što je na tebi i drži ga dobro.” Ona ga pridrža, a on joj nasu šest mjerica ječma i naprti joj. I ode ona u grad."},{"v":16,"t":"Kad je stigla, upita je svekrva: “Što je s tobom, kćeri moja?” A ona joj pripovjedi sve što je učinio za nju."},{"v":17,"t":"I nadoveza: “Ovih šest mjerica ječma dade mi kazujući: 'Ne smiješ se vratiti svekrvi praznih ruku.'”"},{"v":18,"t":"Nato će joj Noemi: “Budi mirna, kćeri moja, dok ne vidiš što će biti: jer neće on imati spokoja dok sve još danas ne dokrajči.”"}]},"4":{"hr":[{"v":1,"t":"Boaz potom iziđe na gradska vrata i sjede ondje. I gle, naiđe onaj skrbnik o kome je govorio. I dozva ga Boaz: “Ej, hodi ovamo i sjedni!” Onaj dođe i sjede."},{"v":2,"t":"Onda Boaz uze deset ljudi između starješina gradskih i reče: “Posjedajte ovdje!” I posjedaše."},{"v":3,"t":"Zatim reče skrbniku: “Noemi, koja se vratila s Moapskih polja, htjela bi prodati ono zemlje našega brata Elimeleka."},{"v":4,"t":"Zato sam odlučio da se s tobom razgovorim i predložim ti: otkupi njivu pred ovima koji sjede ovdje i pred starješinama moga naroda. Ako je kaniš otkupiti, onda otkupi; ako ne kaniš, kaži mi da znam. Jer prije tebe nema nitko pravo na otkup; ja sam na redu tek iza tebe.” A onaj reče: “Hoću, otkupit ću je.”"},{"v":5,"t":"Onda kaza Boaz: “Kad uzmeš zemlju iz ruke Noemi, treba da uzmeš i Rutu Moapku, pokojnikovu ženu, da se pokojniku sačuva ime na baštini.”"},{"v":6,"t":"Ali skrbnik reče: “E, onda ne mogu biti otkupnik, da ne raspem svoje baštine. Otkupi ti po svome skrbničkom pravu jer ja ne mogu.”"},{"v":7,"t":"A bijaše od starine običaj u Izraelu: da se čemu potkrijepi valjanost otkupa ili zamjene, čovjek bi izuo sandalu i dao je drugome. To bijaše svjedočanstvo u Izraelu."},{"v":8,"t":"Tako dakle i onaj skrbnik reče Boazu: “Otkupi ti!” te izu sandalu i dade mu je."},{"v":9,"t":"Tada Boaz kaza starješinama i svemu narodu: “Vi ste danas svjedoci da ja otkupljujem iz ruke Noemine sve ono što je bilo Elimelekovo, sve što je bilo Kiljonovo i Mahlonovo."},{"v":10,"t":"Uz to uzimam za ženu Rutu Moapku, ženu Mahlonovu, da bi se sačuvalo ime pokojnikovo na baštini i da se ime njegovo ne bi zatrlo među braćom njegovom i nestalo s vrata zavičaja njegova. Vi ste danas tome svjedoci.”"},{"v":11,"t":"Sav narod koji se nalazio na vratima gradskim i starješine rekoše: “Svjedoci smo! Dao Jahve da žena koja ulazi u dom tvoj bude kao Rahela i Lea, koje su obje podigle kuću Izraelovu! Obogati se u Efrati, a prodiči u Betlehemu!"},{"v":12,"t":"Neka tvoja kuća, po potomstvu koje će ti dati Jahve od ove mlade žene, bude kao kuća Peresa, koga Judi rodi Tamara!”"},{"v":13,"t":"Tako Boaz uze Rutu i ona posta žena njegova. Uđe on k njoj i Jahve joj dade te ona zatrudnje i rodi sina."},{"v":14,"t":"Onda žene rekoše Noemi: “Blagoslovljen bio Jahve koji ti danas nije uskratio skrbnika! I prodičio njegovo ime u Izraelu!"},{"v":15,"t":"On će biti tvoja utjeha i potpora starosti tvojoj; jer ga rodi snaha tvoja koja te ljubi i koja ti vrijedi više od sedam sinova.”"},{"v":16,"t":"Noemi uze dječaka, metnu ga sebi na krilo i bi mu odgojiteljicom."},{"v":17,"t":"Susjede mu nadjenuše ime govoreći: “Noemi se rodio sin!” I prozvaše ga Obed; on je otac Jišaja, oca Davidova."},{"v":18,"t":"A ovo je rodoslovlje Peresovo: Peres imade sina Hesrona,"},{"v":19,"t":"Hesron Rama, Ram Aminadaba,"},{"v":20,"t":"Aminadab Nahšona, Nahšon Salmona,"},{"v":21,"t":"Salmon Boaza, Boaz Obeda,"},{"v":22,"t":"Obed Jišaja, a Jišaj Davida."}]}},"1SA":{"1":{"hr":[{"v":1,"t":"Bio jedan čovjek iz Ramatajima, Sufovac iz Efrajimove gore, po imenu Elkana, sin Jerohama, sina Elihua, sina Tohua, sina Sufova, Efrajimljanin."},{"v":2,"t":"Imao je dvije žene: ime jednoj bijaše Ana, a drugoj bijaše ime Penina. Penina je imala djece, a Ana ih nije imala."},{"v":3,"t":"Taj je čovjek svake godine uzlazio iz svoga grada da se pokloni i prinese žrtvu Jahvi Sebaotu u Šilu. Ondje su bila dva sina Elijeva, Hofni i Pinhas, kao svećenici Jahvini."},{"v":4,"t":"Jednoga dana Elkana prinese žrtvu. On je obično svojoj ženi Penini i svim njezinim sinovima i kćerima davao više žrtvenih dijelova,"},{"v":5,"t":"a Ani je davao samo jedan dio, premda je više ljubio Anu, ali Jahve joj ne bijaše dao od srca poroda."},{"v":6,"t":"Uz to joj je suparnica njezina zanovijetala da je ponizi što joj Jahve ne bijaše dao od srca poroda."},{"v":7,"t":"Tako je bivalo svake godine kad god bi polazili u Dom Jahvin: Penina je zanovijetala Ani. Ana je stoga plakala i nije htjela jesti."},{"v":8,"t":"Tada joj reče Elkana, njezin muž: “Zašto plačeš, Ana? I zašto ne jedeš? Zašto ti je srce rastuženo? Nisam li ti ja vredniji nego deset sinova?”"},{"v":9,"t":"Ali Ana ustade, pošto su jeli i pili u sobi, i stupi pred Jahvu - a svećenik Eli sjeđaše na stolici na pragu svetišta Jahvina."},{"v":10,"t":"I ojađena u duši pomoli se Ana Jahvi, plačući gorko."},{"v":11,"t":"I zavjetova se ovako: “Jahve Sebaote! Ako pogledaš na nevolju službenice svoje i opomeneš se mene i ne zaboraviš službenice svoje te dadeš službenici svojoj muško čedo, ja ću ga darovati Jahvi za sve dane njegova života i britva neće prijeći preko glave njegove.”"},{"v":12,"t":"Tako se ona dugo molila pred Jahvom, a Eli je motrio usta njezina."},{"v":13,"t":"Ana govoraše u srcu; samo se usne njezine micahu, a glas joj se nije čuo. Zato Eli pomisli da je pijana."},{"v":14,"t":"I reče joj Eli: “Dokle ćeš biti pijana? Otrijezni se od vina što je u tebi!”"},{"v":15,"t":"Ali Ana odgovori i reče: “Nisam pijana, gospodaru, nego sam velika nesretnica. Nisam pila ni vina ni opojna pića nego izlijevam dušu svoju pred Jahvom."},{"v":16,"t":"Ne sudi službenicu svoju kao ženu nevaljalu, jer sam od preteške tuge i žalosti tako dugo molila.”"},{"v":17,"t":"Tada joj Eli odgovori ovako: “Pođi u miru! A Bog Izraelov neka ti ispuni molitvu kojom si ga molila.”"},{"v":18,"t":"A ona reče: “Neka službenica tvoja nađe milost u očima tvojim!” I žena ode svojim putem: jela je i lice joj nije više bilo tužno kao i prije."},{"v":19,"t":"Sutradan uraniše i pokloniše se Jahvi, a onda se vratiše i dođoše svojoj kući u Ramu. Elkana pozna Anu, ženu svoju, a Jahve je se opomenu."},{"v":20,"t":"Ana zatrudnje i, kad bi vrijeme, rodi sina koga nazva imenom Samuel, “jer sam ga”, reče, “izmolila od Jahve”."},{"v":21,"t":"Poslije godine dana uziđe njezin muž Elkana sa svim domom svojim da prinese Jahvi godišnju žrtvu i da izvrši zavjet."},{"v":22,"t":"Ali Ana ne pođe s njim jer reče svome mužu: “Neću poći dok se dijete ne odbije od prsiju, a onda ću ga odvesti da se pokaže pred Jahvom i da ostane ondje zauvijek.”"},{"v":23,"t":"I odgovori joj Elkana, njezin muž: “Čini kako misliš da je dobro; ostani dok ga ne odbiješ od prsiju; samo neka ti Jahve ispuni tvoju želju!” I žena osta kod kuće dojeći sina svoga dok ga nije odbila od prsiju."},{"v":24,"t":"Čim ga je odbila od prsiju, povede ga sa sobom uzevši uz to trogodišnjeg junca, efu brašna i mijeh vina; i uvede ga u Dom Jahvin u Šilu. A dječak je bio još vrlo mlad."},{"v":25,"t":"Tada zaklaše junca, a majka dječakova pristupi k Eliju."},{"v":26,"t":"I reče Ana: “Dopusti, gospodaru! Tako ti života tvoga, gospodaru, ja sam ona žena koja je stajala ovdje kraj tebe moleći se Jahvi."},{"v":27,"t":"Molila sam za ovo dijete, i Jahve mi je uslišio prošnju kojom sam ga prosila."},{"v":28,"t":"Zato i ja njega ustupam Jahvi za sve dane njegova života: ta isprošen je od Jahve.” I pokloniše se ondje Jahvi."}]},"2":{"hr":[{"v":1,"t":"Nato se Ana pomoli ovako: “Kliče srce moje u Jahvi, raste snaga moja po Bogu mom. Šire mi se usta na dušmane moje, jer se radujem pomoći tvojoj."},{"v":2,"t":"Nitko nije svet kao što je Jahve (jer nema nikoga osim tebe), i nema hridi kao što Bog je naš."},{"v":3,"t":"Ne govorite mnogo hvastavih riječi, neka ne izlazi drskost iz usta vaših, jer Jahve je sveznajući Bog, pravo on prosuđuje djela."},{"v":4,"t":"Lomi se luk junacima, nemoćni se snagom opasuju."},{"v":5,"t":"Nekoć siti sad se za kruh muče, nekoć gladni ne gladuju više. Nerotkinja rađa sedam puta, majka brojne djece svježinu izgubi."},{"v":6,"t":"Jahve daje smrt i život, ruši u Šeol i odande diže."},{"v":7,"t":"Jahve čini uboga i bogata, obara čovjeka i uzvisuje."},{"v":8,"t":"Diže slabića iz prašine, iz bunjišta izvlači uboga, da ih posadi s knezovima i da im odredi počasna mjesta. Jer Jahvini su stupovi zemlje, na njih je stavio ovaj svijet."},{"v":9,"t":"Korake čuva svojih vjernika, zlikovce stiže propast u mraku (svojom snagom čovjek ne stječe pobjede)."},{"v":10,"t":"Koji se protive Jahvi, padaju, Svevišnji grmi s nebesa. Jahve sudi međama zemlje, daje silu svojemu kralju, uzdiže snagu pomazanika svoga.”"},{"v":11,"t":"Potom se Ana vrati u Ramu, a dječak ostade da služi Jahvi pod okom svećenika Elija."},{"v":12,"t":"A Elijevi sinovi bijahu nevaljali ljudi jer nisu marili za Jahvu"},{"v":13,"t":"ni za prava svećenika nasuprot narodu: kad bi tko prinosio žrtvu, došao bi sluga svećenikov, dok se meso još kuhalo, s trorogom vilicom u ruci"},{"v":14,"t":"i zabadao njom u kotlić ili u lonac, u tavu ili u zdjelu, i što god bi se nabolo na vilicu, uzimao je svećenik sebi. Tako su činili svim Izraelcima što su dolazili onamo, u Šilo."},{"v":15,"t":"Tako i prije nego bi se spalilo salo, došao bi sluga svećenikov i rekao čovjeku koji je prinosio žrtvu: “Daj mi mesa da ispečem svećeniku! On neće od tebe kuhana mesa nego samo sirovo.”"},{"v":16,"t":"Ako bi mu čovjek tada rekao: “Neka se najprije spali salo, a onda uzmi što ti duša želi”, on bi odgovorio: “Ne, nego daj odmah! Ako ne daš, uzet ću silom.”"},{"v":17,"t":"Grijeh je mladića bio vrlo velik pred Jahvom, jer su ljudi prezirali žrtvu koja se prinosila Jahvi."},{"v":18,"t":"A Samuel služaše pred Jahvom, još dijete u oplećku lanenom."},{"v":19,"t":"Mati bi mu njegova napravila dolamicu i donosila mu je svake godine kad bi dolazila s mužem svojim da prinese godišnju žrtvu."},{"v":20,"t":"A Eli bi blagoslovio Elkanu i njegovu ženu govoreći: “Neka ti Jahve dade poroda od te žene na uzdarje za dar što ga je dala Jahvi.” Nato bi se vraćali svojoj kući."},{"v":21,"t":"Jahve pohodi Anu i ona zatrudnje i rodi još tri sina i dvije kćeri. A mladi je Samuel rastao pred Jahvom."},{"v":22,"t":"Eli je bio već vrlo star, ali je ipak čuo sve što su njegovi sinovi činili svemu Izraelu."},{"v":23,"t":"I on im reče: “Zašto radite takvo što da o tome moram slušati od svega ovog naroda?"},{"v":24,"t":"Nemojte tako, sinovi moji! Nisu dobri glasovi što ih čujem ... Sablažnjujete narod Jahvin."},{"v":25,"t":"Ako čovjek zgriješi čovjeku, Bog će prosuditi. Ali ako čovjek zgriješi Jahvi, tko će se zauzeti za njega?” Ali sinovi ne poslušaše glasa oca svojega, jer je Jahve odlučio da ih pogubi."},{"v":26,"t":"A mladi je Samuel sve više rastao u dobi i mudrosti i pred Jahvom i pred ljudima."},{"v":27,"t":"Uto dođe jedan Božji čovjek k Eliju i reče mu: “Ovako govori Jahve: 'Nisam li se jasno objavio domu oca tvojega kad su bili u Egiptu, robovi u kući faraonovoj?"},{"v":28,"t":"Odabrao sam ih između svih plemena Izraelovih da mi budu svećenici, da se uspinju na moj žrtvenik, da prinose žrtve paljenice i da nose oplećak preda mnom: i dao sam domu oca tvojega sve paljene žrtve sinova Izraelovih."},{"v":29,"t":"Zašto gledaš zavidnim okom žrtvu i prinos što sam ih odredio za svoj Dom? I zašto paziš sinove svoje više nego mene, toveći ih najboljim dijelovima svih žrtvenih prinosa naroda moga Izraela?"},{"v":30,"t":"Zato sam - riječ je Jahve, Boga Izraelova - rekao doduše da će dom tvoj i dom oca tvojega stupati preda mnom dovijeka, ali sada - riječ je Jahvina - neka je to daleko od mene! Jer ja častim one koji mene časte, a koji mene preziru, bit će osramoćeni."},{"v":31,"t":"Gle, dolaze dani kad ću odsjeći mišicu tvoju i mišicu doma oca tvojega, tako da više neće biti starca u tvom domu."},{"v":32,"t":"Ti ćeš kivnim okom gledati na sve dobro kojim ću obasuti Izraela, i nikada više neće biti starca u tvom domu."},{"v":33,"t":"Zadržat ću ipak nekoga od tvojih kod oltara svoga, samo zato da mu sahnu oči i vene duša njegova, ali sve mnoštvo doma tvoga poginut će od ljudskoga mača."},{"v":34,"t":"Znak će ti biti ono što će stići oba tvoja sina, Hofnija i Pinhasa: obojica će poginuti istoga dana."},{"v":35,"t":"Ja ću sebi podići vjerna svećenika koji će raditi po mom srcu i po mojoj želji i njemu ću sazdati trajan dom, i on će svagda stupati pred pomazanikom mojim."},{"v":36,"t":"A koji god ostane od tvoga doma, dolazit će da mu se pokloni i da izmoli srebrn novčić ili hljeb kruha i kazat će: 'Molim te, primi me u kakvu god službu svećeničku, da imam zalogaj kruha.'”"}]},"3":{"hr":[{"v":1,"t":"Mladi je Samuel služio Jahvi pod nadzorom Elijevim; u ono vrijeme Jahve je izrijetka govorio ljudima, a viđenja nisu bila česta."},{"v":2,"t":"No jednoga je dana Eli ležao u svojoj sobi - oči su njegove počele slabiti te više nije mogao vidjeti -"},{"v":3,"t":"svijećnjak Božji još ne bijaše ugašen i Samuel je spavao u svetištu Jahvinu, ondje gdje je bio Kovčeg Božji."},{"v":4,"t":"I Jahve zovnu: “Samuele! Samuele!” A on odgovori: “Evo me!”"},{"v":5,"t":"I otrča k Eliju i reče: “Evo me! Ti si me zvao!” A Eli reče: “Ja te nisam zvao. Vrati se i spavaj!” I on ode i leže."},{"v":6,"t":"I Jahve opet zovnu: “Samuele! Samuele!” Samuel usta, ode k Eliju i reče: “Evo me! Ti si me zvao!” A Eli odgovori: “Ja te nisam zvao, sine! Vrati se i spavaj!”"},{"v":7,"t":"Samuel još nije poznavao Jahve i još mu nikada ne bijaše objavljena riječ Jahvina."},{"v":8,"t":"I Jahve zovnu Samuela po treći put. On usta, ode k Eliju i reče: “Evo me! Ti si me zvao!” Sada Eli razumje da je Jahve zvao dječaka."},{"v":9,"t":"Zato reče Samuelu: “Idi i lezi; a ako te zovne, ti reci: 'Govori, sluga tvoj sluša.'” I Samuel ode i leže na svoje mjesto."},{"v":10,"t":"I dođe Jahve i stade i zovnu kao prije: “Samuele! Samuele!” A Samuel odgovori: “Govori, sluga tvoj sluša.”"},{"v":11,"t":"Tada Jahve reče Samuelu: “Evo, učinit ću nešto u Izraelu da će oba uha zujati svakome koji čuje."},{"v":12,"t":"U onaj ću dan ispuniti na Eliju sve što sam rekao za kuću njegovu, od početka do kraja."},{"v":13,"t":"Ti ćeš mu objaviti da osuđujem kuću njegovu dovijeka; on je znao da njegovi sinovi hule na Boga, a nije ih obuzdao."},{"v":14,"t":"Zato - kunem se domu Elijevu - neće oprati krivicu Elijeva doma nikakve žrtve ni prinosi dovijeka.”"},{"v":15,"t":"Samuel je spavao do jutra, a onda otvori vrata Doma Jahvina. Samuel se bojao kazati viđenje Eliju."},{"v":16,"t":"Ali Eli zovnu Samuela govoreći: “Samuele, sine!” A on odgovori: “Evo me!”"},{"v":17,"t":"I on upita: “Kakva je riječ koju ti reče? Nemoj mi zatajiti ništa! Tako ti Bog učinio zlo i dodao ti drugo ako mi zatajiš nešto od onoga što ti je kazao.”"},{"v":18,"t":"Nato mu Samuel pripovjedi sve i ništa ne zataji od njega. A Eli reče: “On je Jahve, neka čini što je dobro u očima njegovim!”"},{"v":19,"t":"Samuel je rastao, a Jahve je bio s njim i nije pustio da ijedna od njegovih riječi padne na zemlju."},{"v":20,"t":"Sav Izrael, od Dana do Beer Šebe, spozna da je Samuel postavljen za proroka Jahvina."},{"v":21,"t":"Jahve se i dalje javljao u Šilu, jer se objavljivao Samuelu, [4:1] i riječ se Samuelova obraćala svemu Izraelu. (Eli je bio vrlo star, a njegovi su sinovi ustrajali u svome opakom postupku pred Jahvom.)"}]},"4":{"hr":[{"v":1,"t":"U ono vrijeme skupiše Filistejci vojsku protiv Izraela. Izraelci iziđoše pred njih da se pobiju i utaboriše se kod Eben Haezera, dok su Filistejci udarili tabor kod Afeka."},{"v":2,"t":"Filistejci se svrstaše u bojni red protiv Izraela i nasta žestoka bitka. Izrael podleže Filistejcima: oko četiri tisuće ljudi pogibe na bojištu, na otvorenu polju."},{"v":3,"t":"Kad se narod vratio u tabor, rekoše starješine Izraelove: “Zašto je Jahve dopustio da nas Filistejci danas pobijede? Pođimo u Šilo po Kovčeg saveza Jahvina neka dođe u našu sredinu i spasi nas iz ruku naših neprijatelja.”"},{"v":4,"t":"Narod posla ljude u Šilo i donesoše odande Kovčeg saveza Jahve nad vojskama, koji stoluje nad kerubinima; oba sina Elijeva, Hofni i Pinhas, dođoše kao pratioci Kovčega."},{"v":5,"t":"Kad je Kovčeg Jahvin stigao u tabor, sav Izrael podiže gromki poklik, od kojega odjeknu zemlja."},{"v":6,"t":"Filistejci čuše taj gromki poklik i zapitaše: “Što znači taj gromki poklik u taboru Hebreja?” I shvatiše da je Kovčeg Jahvin stigao u njihov tabor."},{"v":7,"t":"Tada Filistejce obuze strah jer su govorili: “Bog je došao u tabor!” I povikaše: “Jao nama! Tako nije bilo dosad."},{"v":8,"t":"Jao nama! Tko će nas izbaviti iz ruke toga silnog Boga? To je onaj koji je udario Egipat svakojakim nevoljama."},{"v":9,"t":"Ohrabrite se i budite junaci, Filistejci, da ne postanete robovi Hebrejima kao što su oni bili robovi vama; budite junaci i borite se!”"},{"v":10,"t":"Tada Filistejci zametnuše bitku, Izraelci biše potučeni i pobjegoše svaki u svoj šator. Poraz je bio silan, jer je trideset tisuća pješaka poginulo na izraelskoj strani."},{"v":11,"t":"I Kovčeg Božji bi otet, i oba sina Elijeva poginuše, Hofni i Pinhas."},{"v":12,"t":"Jedan Benjaminovac otrča iz bojnih redova i stiže u Šilo još istoga dana, razderanih haljina i glave posute prašinom."},{"v":13,"t":"Kad je stigao, Eli je sjedio na svojoj stolici, pokraj vrata, pazeći na cestu, jer mu je srce strepilo za Kovčeg Božji. Taj dakle čovjek dođe da gradu donese glas, i nasta silna vika po svem gradu."},{"v":14,"t":"Kad je Eli čuo viku, upita: “Kakva je to velika vika?” Čovjek se požuri i dođe da obavijesti Elija. -"},{"v":15,"t":"A Eliju bijaše devedeset i osam godina, oči mu bijahu ukočene te ništa više nije vidio. -"},{"v":16,"t":"Čovjek reče Eliju: “Dolazim s bojišta, danas sam utekao iz boja.” Tada starac zapita: “Što se dogodilo, sine?”"},{"v":17,"t":"Glasnik odgovori: “Izrael je pobjegao pred Filistejcima, bio je to težak poraz za narod i još su oba tvoja sina poginula i Kovčeg je Božji otet!”"},{"v":18,"t":"Kad je spomenuo Kovčeg Božji, pade Eli sa stolice nauznak kraj vrata, slomi vrat i umrije, jer je bio star čovjek i težak. Bio je sudac u Izraelu četrdeset godina."},{"v":19,"t":"Njegova snaha, žena Pinhasova, bijaše trudna i pred porodom. Kad je čula vijest da je otet Kovčeg Božji i da je umro njezin svekar i poginuo njezin muž, savila se i rodila jer su je najednom uhvatili trudovi."},{"v":20,"t":"Kako je bila na samrti, rekoše joj žene koje stajahu oko nje: “Budi bez brige jer si rodila sina!” Ali ona ne odgovori niti obrati misli na to."},{"v":21,"t":"Djetetu nadjenu ime Ikabod govoreći: “Otišla je slava od Izraela.” Time je mislila na oteti Kovčeg Božji i na svoga svekra i svoga muža."},{"v":22,"t":"Zato reče: “Otišla je slava od Izraela” jer je otet Kovčeg Božji."}]},"5":{"hr":[{"v":1,"t":"Kad su Filistejci osvojili Kovčeg Božji, prenesoše ga iz Eben Haezera u Ašdod."},{"v":2,"t":"Nato Filistejci uzeše Kovčeg Božji, unesoše ga u hram Dagonov i smjestiše pokraj Dagona."},{"v":3,"t":"Sutradan ujutro, kad su žitelji Ašdoda došli u hram Dagonov, gle, Dagon ležaše ničice na zemlji pred Kovčegom Jahvinim. Oni digoše Dagona i metnuše ga natrag na njegovo mjesto."},{"v":4,"t":"Ali kad su ujutro uranili, gle, Dagon opet ležaše ničice na zemlji pred Kovčegom Jahvinim; glava Dagona i obje njegove ruke ležahu odsječene na pragu: na mjestu je stajao samo Dagonov trup."},{"v":5,"t":"Zato Dagonovi svećenici i svi koji ulaze u Dagonov hram ne staju nogom na prag Dagonov u Ašdodu sve do današnjeg dana."},{"v":6,"t":"Tada ruka Jahvina teško pritisnu žitelje Ašdoda i natjera ih u silan strah: udari ih čirevima, Ašdod i njegovo područje."},{"v":7,"t":"Kad su ljudi u Ašdodu vidjeli što se dogodilo, rekoše: “Kovčeg Boga Izraelova ne smije ostati kod nas jer se ruka njegova ispriječila protiv nas i protiv našega boga Dagona.”"},{"v":8,"t":"Oni sazvaše i okupiše sve knezove filistejske k sebi i rekoše: “Što da radimo s Kovčegom Boga Izraelova?” A oni odgovoriše: “U Gat neka se prenese Kovčeg Boga Izraelova.” I prenesoše Kovčeg Boga Izraelova onamo."},{"v":9,"t":"Ali kad su ga prenijeli, ruka se Jahvina spusti na grad i nasta silna strava: udari građane, od najmanjega do najvećega, tako da im se pojaviše čirevi."},{"v":10,"t":"Oni tada poslaše Kovčeg Božji u Ekron. Ali kad je Kovčeg Božji stigao u Ekron, povikaše Ekronjani: “Donesoše Kovčeg Boga Izraelova k meni da pomori mene i sav moj narod!”"},{"v":11,"t":"Zato sazvaše i okupiše sve knezove filistejske i rekoše: “Pošaljite natrag Kovčeg Boga Izraelova, neka se vrati na svoje mjesto da ne pomori mene i moj narod!” Jer vladaše smrtna strava u svemu gradu, toliko ondje bijaše pritisnula ruka Božja."},{"v":12,"t":"Ljudi koji nisu pomrli bili su udareni čirevima i bolni se vapaj grada dizao do neba."}]},"6":{"hr":[{"v":1,"t":"Kovčeg Jahvin bijaše sedam mjeseci u zemlji Filistejaca."},{"v":2,"t":"Tada Filistejci sazvaše svećenike i vrače i zapitaše ih: “Što da radimo s Kovčegom Jahvinim? Poučite nas kako da ga pošaljemo natrag na njegovo mjesto.”"},{"v":3,"t":"Oni odgovoriše: “Ako hoćete vratiti Kovčeg Boga Izraelova, ne šaljite ga natrag prazna nego uza nj pošaljite i naknadnicu. Tada ćete se izliječiti i znat ćete zašto se njegova ruka nije okrenula od vas.”"},{"v":4,"t":"Oni zapitaše: “Kakvu naknadnicu treba da mu pošaljemo?” Oni odgovoriše: “Prema broju filistejskih knezova, pet zlatnih čireva i pet zlatnih štakora, jer je ista nevolja na vama i na vašim knezovima."},{"v":5,"t":"Načinite, dakle, likove svojih čireva i likove svojh štakora, koji vam zatiru zemlju, i dajte slavu Bogu Izraelovu. Možda će dignuti ruku svoju od vas, od vaših bogova i od vaše zemlje."},{"v":6,"t":"Zašto hoćete da vam srce otvrdne kao što je bilo otvrdnulo Egipćanima i faraonu? Kad ih je Bog pritisnuo, nisu li ih onda pustili da odu?"},{"v":7,"t":"Pripremite sada jedna nova kola i uzmite dvije krave dojilice koje još nisu nosile jarma: upregnite krave u kola, a njihovu telad odvedite natrag u staju."},{"v":8,"t":"Tada ćete uzeti Kovčeg Jahvin i staviti ga na kola. Zlatne predmete koje mu prinosite kao žrtvu naknadnicu stavit ćete u kovčežić kraj njega i tako neka pođe."},{"v":9,"t":"Zatim gledajte: ako krene prema svome kraju, put Bet Šemeša, onda je sigurno da nam je on zadao ovo veliko zlo; ako li ne krene tako, znat ćemo da nas nije udarila njegova ruka, nego da nam se to dogodilo slučajno.”"},{"v":10,"t":"Ljudi učiniše tako: uzeše dvije krave dojilice i upregoše ih u kola, a njihovu telad zadržaše u staji."},{"v":11,"t":"Kovčeg Jahvin staviše na kola i kovčežić sa zlatnim štakorima i s likovima svojih čireva."},{"v":12,"t":"Krave udariše ravno cestom prema Bet Šemešu i jednako su išle istim putem, mukale su idući, a nisu skretale ni desno ni lijevo. Filistejski knezovi pratili su ih do granice Bet Šemeša."},{"v":13,"t":"Stanovnici Bet Šemeša upravo su bili zabavljeni žetvom pšenice u dolini. Digavši oči, ugledaše Kovčeg i potrčaše mu s veseljem u susret."},{"v":14,"t":"Kad su kola stigla na polje Jošue iz Bet Šemeša, zaustaviše se. Ondje bijaše velik kamen. Tada iscijepaše drvo od kola i prinesoše krave kao žrtvu paljenicu Jahvi."},{"v":15,"t":"Leviti bijahu skinuli Kovčeg Jahvin i kovčežić što je bio kraj njega i u kojem su bili zlatni predmeti i sve bijahu stavili na onaj veliki kamen. Stanovnici Bet Šemeša prinosili su toga dana žrtve paljenice i klali žrtve klanice Jahvi."},{"v":16,"t":"Kad je to vidjelo pet filistejskih knezova, vratiše se u Ekron isti dan."},{"v":17,"t":"A ovo je pet zlatnih čireva što su ih Filistejci poslali kao žrtvu naknadnicu Jahvi: za Ašdod jedan, za Gazu jedan, za Aškelon jedan, za Gat jedan, za Ekron jedan."},{"v":18,"t":"A zlatnih je štakora bilo toliko koliko svih gradova filistejskih, u svih pet kneževina, od utvrđenih gradova do otvorenih sela. Svjedok je veliki kamen na koji su položili Kovčeg Jahvin i koji još i danas stoji na polju Jošue iz Bet Šemeša."},{"v":19,"t":"Sinovi Jekonijini nisu se radovali sa stanovnicima Bet Šemeša kad su vidjeli Kovčeg Jahvin. Zato je Jahve pobio sedamdeset ljudi među njima. Narod je tugovao zbog toga što ga je Jahve tako teško iskušao."},{"v":20,"t":"Tada ljudi u Bet Šemešu rekoše: “Tko bi mogao opstati pred Jahvom, ovim Svetim Bogom? Kome će otići sada od nas?”"},{"v":21,"t":"I poslaše poslanike stanovnicima Kirjat Jearima i poručiše im: “Filistejci su vratili Kovčeg Jahvin. Dođite i odnesite ga sebi.”"}]},"7":{"hr":[{"v":1,"t":"Tada dođoše ljudi iz Kirjat Jearima i odnesoše Kovčeg Jahvin sebi. Unesoše ga u kuću Abinadabovu, na uzvišici, i posvetiše njegova sina Eleazara da čuva Kovčeg Jahvin."},{"v":2,"t":"Od dana kad je Kovčeg bio postavljen u Kirjat Jearimu, prođe mnogo vremena - dvadeset godina - i sav je dom Izraelov uzdisao za Jahvom."},{"v":3,"t":"Tada Samuel progovori svemu domu Izraelovu ovako: “Ako se od svega srca svoga vraćate Jahvi, uklonite iz svoje sredine tuđe bogove, baale i aštarte, i upravite srce svoje Jahvi i njemu jedinome služite. Tada će vas on izbaviti iz ruke Filistejaca.”"},{"v":4,"t":"Sinovi Izraelovi ukloniše nato baale i aštarte i služahu jedinome Jahvi."},{"v":5,"t":"Samuel tada zapovjedi: “Skupite sve sinove Izraelove u Mispu da se pomolim Jahvi za vas.”"},{"v":6,"t":"Oni se dakle skupiše u Mispi; ondje su grabili vodu i izlijevali je pred Jahvom. I postili su onaj dan i priznavali: “Sagriješili smo Jahvi!” I Samuel je sudio sinovima Izraelovim u Mispi."},{"v":7,"t":"Kad su Filistejci čuli da su se sinovi Izraelovi skupili u Mispi, krenu filistejski knezovi da napadnu na Izraela. Kad to vidješe sinovi Izraelovi, uplašiše se Filistejaca."},{"v":8,"t":"I zamoliše sinovi Izraelovi Samuela: “Ne prestaj vapiti za nas Jahvi, Bogu našemu, da nas izbavi iz ruke Filistejaca.”"},{"v":9,"t":"Samuel uze jedno janje sisanče i prinese ga Jahvi kao žrtvu paljenicu i glasno se pomoli Jahvi za Izraela, i Jahve ga usliša."},{"v":10,"t":"Dok je Samuel prinosio žrtvu paljenicu, Filistejci su došli da udare na Izraela, ali Jahve toga dana zagrmi silnom grmljavinom na Filistejce i tako ih prestraši i smete da su podlegli Izraelu."},{"v":11,"t":"Ratnici izraelski iziđoše iz Mispe i potjeraše Filistejce, tukući ih sve do ispod Bet Kara."},{"v":12,"t":"A Samuel uze jedan kamen i postavi ga između Mispe i Ješane i nazva ga imenom Eben Haezer govoreći: “Dovde nam je Jahve pomogao.”"},{"v":13,"t":"Tako su Filistejci bili poniženi i nikada više ne navališe na zemlju Izraelovu, a ruka je Jahvina pritiskivala Filistejce svega vijeka Samuelova."},{"v":14,"t":"I gradove koje Filistejci bijahu zauzeli od Izraela vratiše se njemu, od Ekrona do Gata, i Izrael oslobodi njihovo područje iz ruke filistejske. I bio je mir između Izraela i Amorejaca."},{"v":15,"t":"Samuel je bio sudac u Izraelu svega svoga vijeka."},{"v":16,"t":"Svake je godine obilazio Betel, Gilgal i Mispu i u svim je tim mjestima sudio Izraelu."},{"v":17,"t":"Zatim se vraćao u Ramu, jer je ondje imao svoju kuću i ondje je sudio Izraelu. Ondje je podigao i žrtvenik Jahvi."}]},"8":{"hr":[{"v":1,"t":"Kad je Samuel ostario, postavio je svoje sinove za suce u Izraelu."},{"v":2,"t":"Njegov prvorođenac zvao se Joel, a drugi sin Abija; oni su bili suci u Beer Šebi."},{"v":3,"t":"Ali sinovi nisu išli stopama očevim: gledali su na svoj dobitak, primali mito i izvrtali pravicu."},{"v":4,"t":"Tada se skupiše sve starješine izraelske i dođoše k Samuelu u Ramu."},{"v":5,"t":"I rekoše mu: “Eto, ti si ostario, a tvoji sinovi ne idu tvojim stopama. Postavi nam, dakle, kralja da nam vlada, kao što je to kod svih naroda.”"},{"v":6,"t":"Ali Samuelu nije bilo drago što su rekli: “Daj nam kralja da nam vlada!” Zato se Samuel pomoli Jahvi."},{"v":7,"t":"A Jahve reče Samuelu: “Poslušaj glas naroda u svemu što od tebe traži, jer nisu odbacili tebe, nego su odbacili mene, ne želeći da ja kraljujem nad njima."},{"v":8,"t":"Sve što su činili meni od onoga dana kad sam ih izveo iz Egipta pa do današnjega dana - ostavili su mene i služili tuđim bogovima - tako oni čine i tebi."},{"v":9,"t":"Sada, dakle, poslušaj njihov zahtjev, ali ih svečano opomeni i pouči o pravima kralja koji će vladati nad njima.”"},{"v":10,"t":"Samuel ponovi sve Jahvine riječi narodu koji je od njega tražio kralja."},{"v":11,"t":"I reče: “Ovo će biti pravo kralja koji će kraljevati nad vama: uzimat će vaše sinove da mu služe kod bojnih kola i kod konja i oni će trčati pred njegovim bojnim kolima."},{"v":12,"t":"Postavljat će ih za tisućnike i pedesetnike; orat će oni njegovu zemlju, žeti njegovu žetvu, izrađivati mu bojno oružje i opremu za njegova bojna kola."},{"v":13,"t":"Uzimat će kralj vaše kćeri da mu priređuju mirisne pomasti, da mu kuhaju i peku."},{"v":14,"t":"Uzimat će najbolja vaša polja, vaše vinograde i vaše maslinike i poklanjat će ih svojim dvoranima."},{"v":15,"t":"Uzimat će desetinu od vaših usjeva i vaših vinograda i davat će je svojim dvoranima i svojim službenicima."},{"v":16,"t":"Uzimat će vaše sluge i vaše sluškinje, vaše najljepše volove i magarce i upotrebljavat će ih za svoj posao."},{"v":17,"t":"Uzimat će desetinu od vaše sitne stoke, a vi sami postat ćete mu robovi."},{"v":18,"t":"I kad jednoga dana budete vapili za pomoć zbog kralja koga ste sami izabrali, Jahve vas neće uslišati u onaj dan!”"},{"v":19,"t":"Narod nije htio poslušati Samuelova glasa nego reče: “Ne! Hoćemo da kralj vlada nad nama!"},{"v":20,"t":"Tako ćemo i mi biti kao svi narodi: sudit će nam naš kralj, bit će nam vođa i vodit će naše ratove.”"},{"v":21,"t":"Kad je Samuel čuo što narod govori, kaza sve Jahvi."},{"v":22,"t":"A Jahve reče Samuelu: “Poslušaj njihovu želju i postavi im kralja!” Tada Samuel reče Izraelcima: “Vratite se svaki u svoj grad!”"}]},"9":{"hr":[{"v":1,"t":"Živio u ono vrijeme jedan čovjek u Benjaminovu plemenu po imenu Kiš, sin Abiela, sina Serora, sina Bekorata, sina Afijahova; bio je iz plemena Benjaminova, čovjek imućan."},{"v":2,"t":"Imao je sina po imenu Šaula, koji je bio mlad i lijep. Među sinovima Izraelovim nije bilo ljepšega čovjeka od njega: za glavu bijaše viši od svega naroda."},{"v":3,"t":"Uto se Kišu, Šaulovu ocu, izgubilo nekoliko magarica, pa Kiš reče svome sinu Šaulu: “Uzmi sa sobom jednoga momka pa ustani i idi tražiti magarice!”"},{"v":4,"t":"I prođoše oni Efrajimovu goru i prođoše zemlju Šališu, ali ne nađoše ništa; prođoše zemlju Šaalim, ali magarica ne bijaše ondje; prođoše i zemlju Benjaminovu, ali ne nađoše ništa."},{"v":5,"t":"Kad su došli u zemlju Suf, reče Šaul momku koji ga je pratio: “Hajde, vratimo se da se ne bi otac okanio magarica i zabrinuo se za nas!”"},{"v":6,"t":"A on mu odgovori: “Eno, u onom ondje gradu živi čovjek Božji; to je vrlo ugledan čovjek: što god rekne, sve se zacijelo ispunja. Pođimo, dakle, k njemu, možda će nas uputiti u ono zbog čega smo pošli na put.”"},{"v":7,"t":"A Šaul reče svome momku: “Ako zaista pođemo onamo, što ćemo ponijeti čovjeku? Kruha je nestalo u našim torbama, nemamo dara da ponesemo čovjeku Božjem. Što mu možemo dati?”"},{"v":8,"t":"A momak opet progovori i reče Šaulu: “Gle, imam u ruci četvrt šekela srebra: dat ću ga Božjem čovjeku da nas uputi kamo bismo išli.”"},{"v":9,"t":"Nekoć se u Izraelu, kad bi išli pitati Boga za savjet, govorilo: “Hajde, pođimo k vidiocu!” Jer koga danas zovu prorokom nekoć se zvao vidjelac. -"},{"v":10,"t":"Šaul odvrati svome momku: “Dobro veliš. Hajdemo!” I krenuše u grad gdje je živio čovjek Božji."},{"v":11,"t":"Kad su se penjali usponom prema gradu, sretoše djevojke koje su izašle da zahvate vode. I zapitaše ih: “Je li gore vidjelac?” -"},{"v":12,"t":"One im odgovore ovako: “Jest, vidjelac je pred vama. Upravo je stigao u grad, jer danas narod ima žrtvu na uzvišici."},{"v":13,"t":"Čim uđete u grad, naći ćete ga još prije nego što se popne na uzvišicu da sudjeluje na žrtvenoj gozbi. Narod neće jesti dok on ne dođe, jer on mora blagosloviti žrtvu, a onda će tek uzvanici jesti. Zato idite odmah gore, jer ćete ga sada još naći.”"},{"v":14,"t":"Oni otiđoše gore u grad. Kad su ulazili na vrata, Samuel ih susrete polazeći na uzvišicu."},{"v":15,"t":"A dan prije nego što je Šaul došao bijaše Jahve objavio Samuelu:"},{"v":16,"t":"“Sutra u ovo doba poslat ću k tebi čovjeka iz Benjaminove zemlje. Ti ćeš ga pomazati za kneza nad mojim narodom Izraelom. On će izbaviti moj narod iz ruke filistejske. Vidio sam nevolju svoga naroda i njegov je vapaj dopro do mene.”"},{"v":17,"t":"A kad je Samuel ugledao Šaula, Jahve mu progovori: “Evo ti čovjeka za koga ti rekoh: 'Taj će vladati nad mojim narodom.'”"},{"v":18,"t":"Šaul pristupi Samuelu na vratima i reče: “Daj mi kaži gdje je vidiočeva kuća.”"},{"v":19,"t":"A Samuel odgovori Šaulu: “Ja sam vidjelac. Pođi preda mnom na uzvišicu, danas ćete sa mnom jesti. Sutra ću te ujutro otpustiti i sve ću ti kazati što ti je na srcu."},{"v":20,"t":"A za magarice koje su ti se izgubile prije tri dana ne uznemiruj se jer su se našle. Uostalom, kome pripada sve što je najdragocjenije u Izraelu? Zar ne tebi i svemu domu tvoga oca?”"},{"v":21,"t":"A Šaul odgovori ovako: “Nisam li ja od Benjaminova plemena, najmanjega plemena Izraelova? A moj rod nije li najneznatniji između svih rodova Benjaminova plemena? Zašto mi, dakle, govoriš takve riječi?”"},{"v":22,"t":"Samuel uze Šaula i njegova momka, odvede ih u sobu i dade im mjesto u pročelju među uzvanicima, kojih je bilo tridesetak."},{"v":23,"t":"Zatim Samuel reče kuharu: “Donesi dio koji ti dadoh i za koji ti rekoh da ga staviš na stranu.”"},{"v":24,"t":"Kuhar uze but, donese ga i stavi pred Šaula, a Samuel mu reče: “Evo, pred tobom je ono što je sačuvano za tebe. Jedi, jer to ti je sačuvano baš za ovu zgodu.” Tako je u onaj dan Šaul jeo sa Samuelom."},{"v":25,"t":"Potom odande siđoše u grad. Ondje prostriješe Šaulu na krovu."},{"v":26,"t":"I on leže na počinak. Čim je svanula zora, Samuel zovnu Šaula (na krovu) govoreći: “Ustani da te otpustim!” Kad je Šaul ustao, izađoše obojica, on i Samuel."},{"v":27,"t":"Kad su došli na kraj grada, reče Samuel Šaulu: “Kaži momku neka pođe naprijed pred nama! A ti stani sada da ti objavim riječ Božju.”"}]},"10":{"hr":[{"v":1,"t":"Tada Samuel uze uljanicu s uljem te je izli na glavu Šaulu; zatim ga poljubi i reče: “Ovim te Jahve pomazao za kneza nad svojim narodom Izraelom. Ti ćeš vladati nad narodom Jahvinim i izbavit ćeš ga iz ruke njegovih neprijatelja unaokolo. I evo ti znaka da te Jahve pomazao za kneza nad svojom baštinom."},{"v":2,"t":"Kad odeš sada od mene, naći ćeš dva čovjeka kod Rahelina groba, na granici zemlje Benjaminove, u Selsahu. Oni će ti reći: 'Našle su se magarice koje si pošao tražiti; i gle, tvoj je otac zaboravio na magarice, a zabrinut je za vas i govori: Što da učinim za svoga sina?'"},{"v":3,"t":"A kad odeš odande dalje i dođeš do Taborskog Hrasta, srest ćeš ondje tri čovjeka koja će ići gore k Bogu u Betel. Jedan će nositi tri jareta, drugi tri okrugla kruha, a treći mijeh vina."},{"v":4,"t":"Oni će te pozdraviti i dat će ti dva kruha, a ti ih primi iz njihove ruke."},{"v":5,"t":"Poslije toga doći ćeš u Gibeu Božju (gdje se nalazi filistejski stup). Kad uđeš u grad, namjerit ćeš se na povorku proroka koji će silaziti s uzvišice, a pred njima harfe, bubnjevi, frule i citre; oni će biti u proročkom zanosu."},{"v":6,"t":"Tada će na te sići duh Jahvin te ćeš pasti u proročki zanos s njima i promijenit ćeš se u drugog čovjeka."},{"v":7,"t":"A kad ti se ispune ti znakovi, onda čini kako ti se prilika pruži jer je Bog s tobom."},{"v":8,"t":"Zatim ćeš sići preda mnom u Gilgal i ja ću sići k tebi da prinesem žrtve paljenice i žrtve pričesnice. Sedam dana čekaj dok ne dođem k tebi i ne poučim te što ćeš činiti.”"},{"v":9,"t":"Čim je Šaul okrenuo leđa da ode od Samuela, Bog mu promijeni srce i svi se oni znakovi ispuniše u onaj dan."},{"v":10,"t":"Kad su, naime, došli u Gibeu, gle, dođe mu u susret povorka proroka i duh Božji siđe na njega te on pade u proročki zanos usred njih."},{"v":11,"t":"I kad su ga svi koji ga poznavahu otprije vidjeli gdje prorokuje s prorocima, počeše govoriti jedan drugome: “Što se to dogodilo sa sinom Kiševim? Zar je Šaul među prorocima?”"},{"v":12,"t":"A jedan od njih odvrati i reče: “A tko je njihov otac?” Otuda je nastala poslovica: “Zar je i Šaul među prorocima?”"},{"v":13,"t":"Kad je prošao njegov zanos, Šaul se vrati kući."},{"v":14,"t":"A Šaulov stric upita njega i njegova momka: “Kamo ste išli?” A Šaul odgovori: “Da tražimo magarice; a kad smo vidjeli da ih nema, otišli smo k Samuelu.”"},{"v":15,"t":"A njegov ga stric zamoli: “Pripovijedaj mi što vam je rekao Samuel.”"},{"v":16,"t":"A Šaul odgovori svome stricu: “Rekao nam je da su se našle magarice.” Ali mu ništa ne reče o kraljevskoj časti koju mu je prorekao Samuel."},{"v":17,"t":"Poslije toga Samuel sazva narod pred Jahvu u Mispu"},{"v":18,"t":"i reče sinovima Izraelovim: “Ovako govori Jahve: 'Ja sam izveo Izraela iz Egipta i izbavio sam vas iz egipatske ruke i iz ruke svih kraljevstava koja su vas tlačila."},{"v":19,"t":"A vi ste danas odbacili svoga Boga, onoga koji vas je izbavljao od svih vaših zala i svih vaših nevolja i rekli ste mu: 'Ne, nego postavi kralja nad nama!' Zato sada stanite pred Jahvom po svojim plemenima i rodovima.'”"},{"v":20,"t":"Potom Samuel privede sva plemena Izraelova i ždrijeb pade na pleme Benjaminovo."},{"v":21,"t":"Zatim privede pleme Benjaminovo po rodovima i ždrijeb pade na Matrijev rod; a kad privede Matrijev rod, čovjeka po čovjeka, ždrijeb pade na Šaula, sina Kiševa; ali kad ga potražiše, na nađoše ga."},{"v":22,"t":"Tada još jednom upitaše Jahvu: “Je li taj čovjek došao ovamo?” A Jahve odgovori: “Eno ga, sakrio se za tovarom.”"},{"v":23,"t":"Otrčaše i dovedoše ga odande; a kad je stao usred naroda, bijaše glavom i ramenima viši od sviju."},{"v":24,"t":"Tada Samuel reče svemu narodu: “Vidite li koga je izabrao Jahve? Nema mu ravna u svemu narodu.” I sav narod uze klicati i vikati: “Živio kralj!”"},{"v":25,"t":"Nato Samuel objavi narodu kraljevsko pravo i zapisa ga u knjigu koju položi pred Jahvu. Najposlije Samuel otpusti sav narod da ide svaki svojoj kući."},{"v":26,"t":"Šaul se također vrati kući u Gibeu, a s njim pođoše junaci kojima je Bog taknuo srce."},{"v":27,"t":"Ali neke ništarije rekoše: “Kako će nas taj spasiti?” I prezreše ga i ne donesoše mu nikakva dara."}]},"11":{"hr":[{"v":1,"t":"Otprilike poslije mjesec dana dođe Amonac Nahaš i utabori se kod Jabeša Gileadskog. Svi Jabešani poručiše Nahašu: “Sklopi savez s nama pa ćemo ti se pokoriti.”"},{"v":2,"t":"Ali im Amonac Nahaš odgovori: “Ovako ću sklopiti savez s vama: svakome ću od vas iskopati desno oko, i tako ću učiniti sramotu svemu Izraelu.”"},{"v":3,"t":"A jabeške mu starješine rekoše: “Ostavi nam sedam dana da pošaljemo glasnike u sve krajeve Izraelove, pa ako se ne nađe nitko da nas izbavi, predat ćemo se tebi.”"},{"v":4,"t":"I dođoše poslanici u Šaulovu Gibeu te izložiše sve narodu da čuje. Tada sav narod zaplaka iza glasa."},{"v":5,"t":"A gle, Šaul je upravo išao za govedima iz polja pa upita: “Što je ljudima te plaču?” I pripovjediše mu što su rekli Jabešani."},{"v":6,"t":"Kad je Šaul čuo te riječi, duh Jahvin siđe na njega i silan gnjev uskipje u njemu."},{"v":7,"t":"I uze on dva vola, isiječe ih i komade razasla po poslanicima u sve krajeve Izraelove i poruči: “Tko ne pođe za Šaulom, ovako će biti s njegovim govedima.” I strah Božji obuze ljude te pođoše kao jedan čovjek."},{"v":8,"t":"Šaul ih izbroji u Bezeku: i bijaše sinova Izraelovih tri stotine tisuća, a Judinih ljudi trideset tisuća."},{"v":9,"t":"Zatim reče poslanicima koji bijahu došli: “Ovako recite Jabešanima u Gileadu: sutra, kad sunce pripeče, stići će vam pomoć.” Kad su se poslanici vratili, javiše sve to Jabešanima i oni se obradovaše."},{"v":10,"t":"I poručiše Nahašu: “Sutra ćemo izaći k vama, pa učinite s nama što vam bude drago.”"},{"v":11,"t":"Sutradan Šaul razdijeli narod u tri čete, koje provališe u tabor o jutarnjoj straži i tukoše Amonce do najveće dnevne žege; a što preživje, rasprša se da ni dvojica ne ostaše zajedno."},{"v":12,"t":"Tada narod reče Samuelu: “Tko je onaj što je govorio: 'Zar će Šaul kraljevati nad nama?' Dajte te ljude da ih pogubimo!”"},{"v":13,"t":"Ali Šaul odgovori: “Neka se ne pogubi u ovaj dan nitko, jer je danas Jahve izvojevao pobjedu u Izraelu.”"},{"v":14,"t":"Tada Samuel reče narodu: “Hajdemo u Gilgal da ondje potvrdimo kraljevstvo.”"},{"v":15,"t":"I sav narod krenu u Gilgal i ondje postaviše Šaula za kralja pred Jahvom, u Gilgalu. Ondje žrtvovaše pred Jahvom žrtve pričesnice i ondje je Šaul sa svim Izraelcima slavio slavlje."}]},"12":{"hr":[{"v":1,"t":"Tada Samuel reče svemu Izraelu: “Evo, ispunio sam vašu želju u svemu što ste od mene tražili i postavih kralja nad vama."},{"v":2,"t":"I od sada će kralj ići pred vama. A ja sam ostario i osijedio i moji sinovi eto su među vama. Ja sam išao pred vama od svoje mladosti pa do današnjega dana."},{"v":3,"t":"Evo me! Posvjedočite protiv mene pred Jahvom i pred njegovim pomazanikom: kome sam oteo vola i kome sam oteo magarca? Koga sam prevario? Koga sam tlačio? Od koga sam primio mito da bih zažmirio na jedno oko? Ja ću vam sve natrag vratiti.”"},{"v":4,"t":"A oni odgovoriše: “Nisi nas prevario, nisi nas tlačio, nisi ni od koga primio ništa.”"},{"v":5,"t":"Još im reče: “Svjedok je Jahve protiv vas i svjedok je njegov pomazanik u ovaj dan da niste našli ništa u mojoj ruci.” A oni odgovoriše: “Tako je!”"},{"v":6,"t":"Tada Samuel reče narodu: “Jest, svjedok je Jahve koji je postavio Mojsija i Arona i koji je izveo vaše oce iz Egipta."},{"v":7,"t":"Stanite sada ovamo da probesjedim s vama pred Jahvom i da vas podsjetim na sva velika djela koja je učinio Jahve vama i vašim ocima."},{"v":8,"t":"Kad je Jakov došao u Egipat, Egipćani su ih pritisnuli, a vaši su oci vapili Jahvi za pomoć. I Jahve posla Mojsija i Arona, koji izvedoše oce vaše iz Egipta i naseliše ih na ovome mjestu."},{"v":9,"t":"Ali oni zaboraviše Jahvu, Boga svoga, i on ih predade u ruke Siseri, vojvodi hasorske vojske, i u ruke Filistejaca, i u ruke moapskome kralju, koji su vojevali na njih."},{"v":10,"t":"I opet su vapili Jahvi za pomoć govoreći: 'Zgriješili smo jer smo ostavili Jahvu i uzeli služiti baalima i aštartama; izbavi nas sada iz ruku naših neprijatelja pa ćemo ti služiti!'"},{"v":11,"t":"I Jahve posla Jerubaala i Baraka, Jiftaha i Samuela te vas izbavi iz ruku vaših neprijatelja unaokolo, tako da ste mogli živjeti bez straha."},{"v":12,"t":"Ali kad vidjeste Nahaša, kralja amonskoga, kako ide na vas, rekoste mi: 'Ne, nego kralj neka vlada nad nama!' Pa ipak je vaš kralj Jahve, vaš Bog!"},{"v":13,"t":"I eto vam sada kralja koga ste izabrali! Eto, Jahve je postavio kralja nad vama."},{"v":14,"t":"Ako se budete bojali Jahve i njemu budete služili, ako budete slušali njegov glas i ne budete se protivili njegovim zapovijedima, slijedit ćete Jahvu, Boga svoga, vi i kralj koji kraljuje nad vama."},{"v":15,"t":"Ako li ne budete slušali Jahvina glasa, ako se budete protivili njegovim zapovijedima, tada će se ruka Jahvina spustiti na vas i na vašega kralja da vas uništi."},{"v":16,"t":"Sada još jednom pristupite i vidite veliki znak koji će Jahve učiniti pred vašim očima."},{"v":17,"t":"Nije li sada pšenična žetva? Ali ja ću zazvati Jahvu i on će poslati gromove i kišu. I jasno ćete razabrati kako je veliko zlo koje ste učinili pred Jahvom tražeći sebi kralja.”"},{"v":18,"t":"Tada Samuel zazva Jahvu i Jahve posla gromove i kišu u onaj dan i sav se narod vrlo poboja Jahve i Samuela."},{"v":19,"t":"I sav narod reče Samuelu: “Moli se Jahvi, svome Bogu, za svoje sluge da ne pomremo, jer smo svim svojim grijesima dodali zlo tražeći sebi kralja.”"},{"v":20,"t":"Ali Samuel reče narodu: “Ne bojte se! Vi ste, doduše, učinili sve ovo zlo, ali sada ne ostavljajte više Jahvu, nego služite Jahvi svim svojim srcem."},{"v":21,"t":"Ne priklanjajte se više ništavim idolima koji vam ništa ne koriste, ništa vam ne pomažu jer su samo ništavila."},{"v":22,"t":"A Jahve neće odbaciti svoga naroda, radi velikog imena svoga, jer se Jahve udostojao da vas učini svojim narodom."},{"v":23,"t":"A od mene neka je daleko da zgriješim Jahvi prestajući moliti za vas i upućivati vas na dobar i pošten put."},{"v":24,"t":"Samo se bojte Jahve i njemu iskreno služite svim svojim srcem; jer, pogledajte kako se velikim očitovao među vama."},{"v":25,"t":"Ako li budete činili zlo, propast ćete vi i vaš kralj.”"}]},"13":{"hr":[{"v":1,"t":"Šaulu je bilo ... godina kad je postao kralj, a kraljevao je ... i dvije godine nad Izraelom."},{"v":2,"t":"Šaul izabra sebi tri tisuće Izraelaca: dvije tisuće od njih bijahu sa Šaulom u Mikmasu i u Betelskoj gori, a jedna tisuća bijaše s Jonatanom u Benjaminovoj Gebi. Ostali je narod Šaul otpustio svakoga u njegov šator."},{"v":3,"t":"Jonatan sruši filistejski stup koji je stajao u Gibei i Filistejci saznaše da su se Hebreji pobunili. Šaul zapovjedi te zatrubiše u rog po svoj zemlji"},{"v":4,"t":"i sav Izrael doznade novost: “Šaul je srušio filistejski stup, Izrael se omrazio Filistejcima!” I narod se poče skupljati oko Šaula u Gilgalu."},{"v":5,"t":"A Filistejci se skupiše da vojuju na Izraela: tri tisuće bojnih kola, šest tisuća konja, a mnoštvo naroda kao pijeska na morskoj obali. I utaboriše se kod Mikmasa, istočno od Bet Avena."},{"v":6,"t":"Kad su Izraelci vidjeli da su u nevolji i da je narod pritisnut od neprijatelja, posakrivaše se u pećine, jame, kamenjake, jarke i čatrnje."},{"v":7,"t":"Neki su prešli i preko gazova Jordana u zemlju Gadovu i Gileadovu. Šaul je još bio u Gilgalu, a sav je narod oko njega drhtao od straha."},{"v":8,"t":"On pričeka sedam dana kako mu je odredio Samuel; ali kad Samuel nije došao u Gilgal, narod se stade razilaziti od Šaula."},{"v":9,"t":"Tada reče Šaul: “Donesite mi žrtvu paljenicu i žrtve pričesnice!” I prinese žrtvu paljenicu."},{"v":10,"t":"I upravo je završavao žrtvu paljenicu, kad eto Samuela; Šaul mu iziđe u susret da ga pozdravi."},{"v":11,"t":"Samuel ga upita: “Što si učinio?” A Šaul odgovori: “Kad sam vidio da se narod razilazi od mene, a ti da ne dolaziš do određenoga dana, a Filistejci se skupili u Mikmasu,"},{"v":12,"t":"pomislio sam: sad će udariti Filistejci na me u Gilgalu, a ja neću stići molitvom ublažiti Jahvu! Zato se odvažih i prinesoh žrtvu paljenicu.”"},{"v":13,"t":"Samuel tada reče Šaulu: “Ludo si radio! Da si održao zapovijed koju ti je dao Jahve, tvoj Bog, Jahve bi učvrstio tvoje kraljevstvo nad Izraelom dovijeka."},{"v":14,"t":"A sada se tvoje kraljevstvo neće trajno održati: Jahve je potražio sebi čovjeka po svom srcu i odredio ga za kneza nad svojim narodom, jer ti nisi održao što ti je Jahve zapovjedio.”"},{"v":15,"t":"Nato Samuel ustade i ode iz Gilgala svojim putem. Što je naroda ostalo, pođe za Šaulom u susret ratnicima. Kad su došli iz Gilgala u Gebu Benjaminovu, Šaul pobroji narod koji je ostao uza nj i bijaše ga oko šest stotina ljudi."},{"v":16,"t":"Šaul i sin mu Jonatan s ljudima što bijahu s njima zaposjeli su Benjaminovu Gebu, a Filistejci se utaborili u Mikmasu."},{"v":17,"t":"Tada iz filistejskog tabora izađe četa pljačkaša u tri odjela: jedan odio udari prema Ofri u zemlju šualsku;"},{"v":18,"t":"drugi odio krenu prema Bet Horonu, a treći odio udari prema Gebi koja se uz Dolinu hijena diže nad pustinjom."},{"v":19,"t":"A po svoj zemlji Izraelovoj nije bilo kovača, jer su Filistejci rekli: “Treba sve učiniti da Hebreji ne bi pravili sebi mačeva i kopalja.”"},{"v":20,"t":"Zato su svi Izraelci išli k Filistejcima ako je tko htio da prekuje svoj raonik ili motiku, svoju sjekiru ili ostan za volove."},{"v":21,"t":"A cijena je bila dvije trećine šekela za raonike i motike, jedna trećina za oštrenje sjekire i za nasađivanje ostana."},{"v":22,"t":"Tako se dogodilo da na dan bitke kod Mikmasa nitko od svega naroda koji bijaše sa Šaulom i Jonatanom nije imao ni mača ni koplja u ruci; samo ih imahu Šaul i njegov sin Jonatan."},{"v":23,"t":"A dotle jedna straža filistejska bijaše izišla prema klancu kod Mikmasa."}]},"14":{"hr":[{"v":1,"t":"Jednoga dana Šaulov sin Jonatan reče svome momku štitonoši: “Hajde da prijeđemo do filistejske straže koja je ondje prijeko.” Svome ocu nije ništa o tom javio."},{"v":2,"t":"Šaul je sjedio na međi Gebe, pod šipkom koji je stajao kraj gumna; a bilo je s njim oko šest stotina ljudi."},{"v":3,"t":"A Ahija, sin Ahituba, brata Ikaboda, sina Pinhasa, sina Elija, svećenika Jahvina u Šilu, nosio je u to vrijeme oplećak. Narod nije primijetio da je Jonatan otišao."},{"v":4,"t":"U sredini klanca kuda je Jonatan htio prijeći da dođe do filistejske straže bila je litica s jedne strane i litica s druge strane. Jedna se zvala Boses, a druga Sene."},{"v":5,"t":"Prva je litica stajala na sjeveru nasuprot Mikmasu, a druga na jugu nasuprot Gebi."},{"v":6,"t":"Jonatan reče svome štitonoši: “Hajde da prijeđemo do straže onih neobrezanika. Možda će Jahve učiniti nešto za nas, jer ništa ne priječi Jahvu da udijeli pobjedu - bilo mnogo ljudi ili malo.”"},{"v":7,"t":"A štitonoša mu odgovori: “Čini sve na što te srce tvoje potiče. Ja ću s tobom, moje je srce kao tvoje srce.”"},{"v":8,"t":"Jonatan mu reče: “Evo, prijeći ćemo k tim ljudima i pokazat ćemo im se."},{"v":9,"t":"Ako nam reknu ovako: 'Ne mičite se dok ne dođemo do vas', tada ćemo se ustaviti na mjestu i nećemo se uspinjati k njima."},{"v":10,"t":"Ako li nam reknu ovako: 'Uspnite se k nama', tada ćemo se uspeti, jer ih je Jahve predao nama u ruke. To će nam biti znak.”"},{"v":11,"t":"Kad su se obojica pokazala filistejskoj straži, rekoše Filistejci: “Gle, Hebreji su počeli izlaziti iz rupa u koje su se skrili.”"},{"v":12,"t":"I stražari doviknuše Jonatanu i njegovu štitonoši: “Uspnite se k nama da vas nešto naučimo!” A Jonatan reče svome štitonoši: “Penji se za mnom, jer ih je Jahve predao u ruke Izraelove.”"},{"v":13,"t":"Jonatan se poče penjati pomažući se rukama i nogama, a za njim njegov štitonoša. Filistejci su padali pred Jonatanom, a njegov ih je štitonoša ubijao za njim."},{"v":14,"t":"U tome prvom pokolju što ga učiniše Jonatan i njegov štitonoša pade dvadesetak ljudi na otprilike pola jutra izoranog polja."},{"v":15,"t":"Tada se proširi strah po taboru i po polju, a i stražare i četu pljačkaša obuze strava; i zemlja zadrhta i bijaše to silan strah Božji."},{"v":16,"t":"A Šaulovi stražari u Benjaminovoj Gebi opaziše da se mnoštvo u taboru uskomešalo na sve strane."},{"v":17,"t":"I Šaul reče ljudima koji su bili s njim: “Prozovite ljude i vidite tko je otišao od nas.” A kad prozvaše, gle, ne bijaše Jonatana i njegova štitonoše!"},{"v":18,"t":"Tada Šaul reče Ahiji: “Primakni oplećak! Posavjetuj se s Jahvom!” On je, naime, tada nosio oplećak pred sinovima Izraelovim."},{"v":19,"t":"Ali dok je Šaul govorio sa svećenikom, bivala je buka u filistejskom taboru sve veća, pa Šaul reče svećeniku: “Povuci ruku!”"},{"v":20,"t":"Nato Šaul i sav narod što je bio s njim krenuše zajedno na mjesto boja, i gle, ondje bijahu isukali mačeve jedni na druge i velika pomutnja vladaše među njima."},{"v":21,"t":"A oni Hebreji koji su već poodavno bili u službi Filistejaca i sada pošli s njima na vojsku, odmetnuše se od njih i pristadoše uz Izraelce koji bijahu sa Šaulom i Jonatanom."},{"v":22,"t":"I svi Izraelci koji se bijahu sakrili u Efrajimovoj gori, čuvši da Filistejci bježe, nagrnuše za njima u boj."},{"v":23,"t":"Tako je Jahve udijelio pobjedu Izraelu u onaj dan, a boj se raširio sve do preko Bet Horona."},{"v":24,"t":"Izraelci su onog dana bili vrlo izmoreni, jer je Šaul izrekao nad narodom ovu zakletvu: “Proklet bio čovjek koji okusi hrane prije večeri, prije nego što se osvetim svojim neprijateljima!” Tako sav narod ne okusi hrane toga dana."},{"v":25,"t":"Ali je ondje bilo medenoga saća na površini zemlje."},{"v":26,"t":"Kad je narod došao onamo, vidje gdje teče med, ali nitko ne prinese ruke k ustima, jer se narod bojao zakletve."},{"v":27,"t":"Samo Jonatan, koji nije čuo kad je njegov otac zakleo narod, primače vrh štapa koji mu bijaše u ruci i zamoči ga u medeno saće, zatim prinese ruku k ustima; i odmah mu se zasvijetliše oči."},{"v":28,"t":"Tada jedan iz naroda progovori i reče mu: “Tvoj je otac zakleo narod govoreći: 'Proklet bio onaj koji okusi hrane danas!'”"},{"v":29,"t":"A Jonatan odgovori: “Moj otac svaljuje nesreću na zemlju. Gledajte kako su mi se zasvijetlile oči jer sam okusio malo toga meda."},{"v":30,"t":"Što bi tek bilo da je narod slobodno jeo od plijena koji je zadobio od neprijatelja? Ne bi li filistejski poraz bio još veći?”"},{"v":31,"t":"Onoga dana potukoše Filistejce od Mikmasa sve do Ajalona, a narod je bio na kraju svojih snaga."},{"v":32,"t":"Tada se narod baci na plijen, nahvata sitne stoke, goveda i teladi i poče ih klati na goloj zemlji i jesti meso s krvlju."},{"v":33,"t":"I javiše to Šaulu govoreći: “Gle, narod griješi Jahvi jedući meso s krvlju!” A on reče: “Iznevjeriste se! Dovaljajte mi ovamo velik kamen!”"},{"v":34,"t":"Zatim reče: “Zađite među narod i recite svima neka svaki dovede k meni svoga vola ili ovcu; ovdje ćete ih klati i jesti, a nećete griješiti Jahvi jedući meso s krvlju.” Tako sav narod još iste noći dovede što je tko imao i to su ondje klali."},{"v":35,"t":"A Šaul podiže žrtvenik Jahvi; bijaše to prvi žrtvenik koji je podigao Jahvi."},{"v":36,"t":"Nato reče Šaul: “Pođimo još noćas u potjeru za Filistejcima i plijenimo ih dok ne svane jutro! Nećemo im ostaviti nijednoga čovjeka!” A narod mu odgovori: “Čini sve što misliš da je dobro!” Ali svećenik reče: “Pristupimo ovdje k Bogu!”"},{"v":37,"t":"I Šaul upita Boga: “Moram li poći u potjeru za Filistejcima? Hoćeš li ih predati u ruke Izraelu?” Ali mu ne odgovori u onaj dan."},{"v":38,"t":"Zato Šaul reče: “Pristupite ovamo, svi narodni glavari! Ispitajte i vidite u čemu je bio današnji prestupak."},{"v":39,"t":"Jer, živoga mi Jahve, koji daje pobjedu Izraelu, ako se nađe krivnja ma i na mome sinu Jonatanu, mora umrijeti!” Ali nitko se iz naroda ne usudi odgovoriti Šaulu."},{"v":40,"t":"Šaul onda reče svemu Izraelu: “Vi stanite na jednu stranu, a ja i moj sin Jonatan stat ćemo na drugu stranu.” A narod odgovori Šaulu: “Čini ono što misliš da je dobro!”"},{"v":41,"t":"Tada se Šaul pomoli: “Jahve, Bože Izraelov, zašto nisi danas odgovorio svome sluzi? Ako je krivnja na meni ili na mome sinu Jonatanu, Jahve, Bože Izraelov, daj Urim; ako li je krivnja na tvom narodu Izraelu, daj Tumim.” I ždrijeb pade na Šaula i Jonatana, a narod izađe slobodan."},{"v":42,"t":"Šaul nastavi: “Bacite ždrijeb između mene i moga sina Jonatana!” I ždrijeb pade na Jonatana."},{"v":43,"t":"Tada Šaul reče Jonatanu: “Priznaj mi što si učinio!” Jonatan odgovori: “Ja sam samo okusio malo meda vrškom štapa koji mi bijaše u ruci. Evo me, spreman sam umrijeti!”"},{"v":44,"t":"Šaul odgovori: “Tako mi Bog učinio zlo i dodao mi drugo ako doista ne umreš, Jonatane!”"},{"v":45,"t":"Ali narod reče Šaulu: “Zar da umre Jonatan, koji je izvojevao ovu veliku pobjedu u Izraelu? Ne smije to biti! Živoga nam Jahve, nijedna vlas neće pasti s njegove glave na zemlju jer je on s Bogom izvršio ovo djelo danas!” Tako ga narod izbavi te Jonatan ne pogibe."},{"v":46,"t":"Šaul odusta od potjere za Filistejcima, a Filistejci se vratiše u svoj kraj."},{"v":47,"t":"Kad je Šaul učvrstio svoju kraljevsku vlast nad Izraelom, okrenu ratovati protiv svih svojih neprijatelja unaokolo: protiv Moaba, protiv Amonaca, protiv Edoma, protiv Bet Rehoba, protiv kralja Sobe i protiv Filistejaca; kuda god bi se okrenuo, svuda bi pobjeđivao."},{"v":48,"t":"Dao je mnogo dokaza svoje hrabrosti, potukao je Amalečane i izbavio Izraela iz ruku onih koji su ga pljačkali."},{"v":49,"t":"Šaulovi sinovi bijahu Jonatan, Išjo i Malki-Šua, a od njegovih dviju kćeri starija se zvala Meraba, a mlađa Mikala."},{"v":50,"t":"Šaulova se žena zvala Ahinoama, a bila je kći Ahimaasova. Vojvoda njegove vojske zvao se Abner, a bio je sin Nera, Šaulova strica."},{"v":51,"t":"Jer Kiš, Šaulov otac, i Ner, Abnerov otac, bijahu sinovi Abielovi."},{"v":52,"t":"Žestok se rat vodio protiv Filistejaca svega Šaulova vijeka. Koga bi god hrabra ili bojovna čovjeka Šaul vidio, svakoga bi uzimao u svoju službu."}]},"15":{"hr":[{"v":1,"t":"Jednom Samuel reče Šaulu: “Mene je Jahve poslao da te pomažem za kralja nad njegovim narodom Izraelom. Poslušaj, dakle, riječi Jahvine."},{"v":2,"t":"Ovako govori Jahve nad vojskama: 'Odlučio sam osvetiti ono što je Amalek učinio Izraelu zatvarajući mu put kad je izlazio iz Egipta."},{"v":3,"t":"Sada idi i udari na Amaleka, izvrši “herem”, kleto uništenje, na njemu i na svemu što posjeduje; ne štedi ga, pobij muškarce i žene, djecu i dojenčad, goveda i ovce, deve i magarce!'”"},{"v":4,"t":"Šaul sazva narod te ih izbroji u Telamu: bijaše ih dvije stotine tisuća pješaka (i deset tisuća Judejaca)."},{"v":5,"t":"Šaul dođe do amalečkoga grada i postavi zasjedu u dolini potoka."},{"v":6,"t":"Potom Šaul poruči Kenijcima: “Otiđite i odvojite se od Amalečana da vas ne bih istrijebio zajedno s njima, jer ste bili skloni svim Izraelcima kad su izlazili iz Egipta.” I Kenijci se odvojiše od Amalečana."},{"v":7,"t":"Šaul potuče Amalečane od Havile pa sve do Šura, koji leži pred Egiptom."},{"v":8,"t":"I živa uhvati Agaga, amalečkog kralja, a sav narod zatre oštricom mača, izvršujući “herem”, kleto uništenje."},{"v":9,"t":"Ali Šaul i narod poštedješe Agaga i najbolje ovce i najbolja goveda, ugojenu stoku i jaganjce i sve što je bilo dobro. Na svemu tome ne htjedoše izvršiti “herem”; nego što je god od stoke bilo bez cijene i vrijednosti, na tom izvršiše “herem”."},{"v":10,"t":"Zato dođe riječ Jahvina Samuelu ovako:"},{"v":11,"t":"“Kajem se što sam Šaula postavio za kralja: okrenuo se od mene i nije izvršio mojih zapovijedi.” Samuel se ražalosti i svu je noć vapio Jahvi."},{"v":12,"t":"U rano jutro krenu Samuel da potraži Šaula. I javiše Samuelu ovako: “Šaul je otišao u Karmel, i gle, podigao je ondje sebi spomenik; zatim je otišao dalje i sišao u Gilgal.”"},{"v":13,"t":"Kad je Samuel došao k Šaulu, reče mu Šaul: “Blagoslovljen da si od Jahve! Izvršio sam Jahvinu zapovijed.”"},{"v":14,"t":"Ali Samuel upita: “Kakvo je to ovčje blejanje što dopire do mojih ušiju i mukanje goveda koje čujem?”"},{"v":15,"t":"A Šaul odgovori: “Dognali su ih od Amalečana, jer je narod poštedio najbolje ovce i najbolja goveda da ih žrtvuje Jahvi, tvome Bogu. Na svemu drugome izvršili smo 'herem'.”"},{"v":16,"t":"A Samuel reče Šaulu: “Stani da ti kažem što mi je noćas objavio Jahve.” A on reče: “Govori!”"},{"v":17,"t":"Tada će Samuel: “Koliko god si malen sam u svojim očima, ipak si postao glavar Izraelovih plemena. Jahve te pomazao za kralja nad Izraelom."},{"v":18,"t":"Jahve te poslao na vojni pohod i zapovjedio ti: 'Idi, izvrši 'herem' na tim grešnicima, na Amalečanima, vojuj na njih do istrebljenja.'"},{"v":19,"t":"Zašto nisi poslušao riječi Jahvine? Zašto si se bacio na plijen i učinio ono što je zlo u Jahvinim očima?”"},{"v":20,"t":"Šaul odgovori Samuelu: “Ja sam poslušao riječ Jahvinu: poduzeo sam pohod kamo me poslao, doveo sam Agaga, amalečkoga kralja, i izvršio 'herem' na Amalečanima."},{"v":21,"t":"Ali je narod od plijena uzeo ovaca i goveda, i to najbolje na čemu se imao izvršiti 'herem', da žrtvuje Jahvi, tvome Bogu, u Gilgalu.”"},{"v":22,"t":"A Samuel odvrati: “Jesu li Jahvi milije paljenice i klanice nego poslušnost njegovu glasu? Znaj, poslušnost je vrednija od najbolje žrtve, pokornost je bolja od ovnujske pretiline."},{"v":23,"t":"Nepokornost je kao grijeh čaranja, samovolja je kao zločin s idolima. Ti si odbacio riječ Jahvinu, zato je Jahve odbacio tebe da ne budeš više kralj!”"},{"v":24,"t":"Tada Šaul odvrati Samuelu: “Zgriješio sam što sam prekršio Jahvinu zapovijed i tvoje naredbe. Bojao sam se naroda i popustio njegovu zahtjevu."},{"v":25,"t":"A sada mi oprosti moj grijeh i vrati se sa mnom da se poklonim Jahvi.”"},{"v":26,"t":"Ali Samuel odgovori Šaulu: “Neću se vratiti s tobom: ti si odbacio Jahvinu riječ, zato je Jahve odbacio tebe da ne budeš više kralj nad Izraelom.”"},{"v":27,"t":"Kad se Samuel okrenuo da ode, Šaul čvrsto uhvati skut njegova plašta, ali se skut otkide."},{"v":28,"t":"Tada mu reče Samuel: “Danas ti je Jahve otkinuo kraljevstvo nad Izraelom i dao ga tvome susjedu, koji je bolji od tebe.” -"},{"v":29,"t":"Ipak, Slava Izraelova ne laže i ne kaje se, jer nije čovjek da bi se kajao. -"},{"v":30,"t":"Šaul reče: “Sagriješio sam; ali mi sada učini čast pred starješinama moga naroda i pred Izraelom i vrati se sa mnom da se poklonim Jahvi, tvome Bogu.”"},{"v":31,"t":"I Samuel se vrati sa Šaulom i Šaul se pokloni Jahvi."},{"v":32,"t":"Potom zapovjedi Samuel: “Dovedite k meni Agaga, amalečkoga kralja!” I Agag dođe k njemu opirući se i reče: “Zaista, smrt je gorka!”"},{"v":33,"t":"Samuel mu odvrati: “Kao što je tvoj mač mnogim ženama oteo djecu, tako će među ženama tvoja majka ostati bez djeteta!” I Samuel posiječe Agaga pred Jahvom u Gilgalu."},{"v":34,"t":"Potom Samuel ode u Ramu, a Šaul se vrati svojoj kući u Šaulovu Gibeu."},{"v":35,"t":"I Samuel nije više vidio Šaula do svoga smrtnog dana. Samuel je tugovao zbog Šaula, ali se Jahve pokajao što je Šaula postavio za kralja nad Izraelom."}]},"16":{"hr":[{"v":1,"t":"Jahve reče Samuelu: “Dokle ćeš tugovati zbog Šaula, kad sam ga ja odbacio da ne kraljuje više nad Izraelom? Napuni uljem svoj rog i pođi na put! Ja te šaljem Betlehemcu Jišaju, jer sam između njegovih sinova izabrao sebi kralja.”"},{"v":2,"t":"A Samuel reče: “Kako bih mogao ići onamo? Šaul će to čuti i ubit će me!” Ali mu Jahve odgovori: “Uzmi sa sobom junicu pa reci: 'Došao sam da žrtvujem Jahvi!'"},{"v":3,"t":"I pozovi Jišaja na žrtvu, a ja ću te sam poučiti što ćeš činiti: pomazat ćeš onoga koga ti kažem.”"},{"v":4,"t":"Samuel učini kako mu je zapovjedio Jahve. Kad je došao u Betlehem, gradske mu starješine dršćući dođu u susret i zapitaju: “Znači li tvoj dolazak dobro?”"},{"v":5,"t":"Samuel odgovori: “Da, dobro! Došao sam da žrtvujem Jahvi. Očistite se i dođite sa mnom na žrtvu!” Potom očisti Jišaja i njegove sinove i pozva ih na žrtvu."},{"v":6,"t":"Kad su došli i kad je Samuel vidio Eliaba, reče u sebi: “Jamačno, evo pred Jahvom stoji njegov pomazanik!”"},{"v":7,"t":"Ali Jahve reče Samuelu: “Ne gledaj na njegovu vanjštinu ni na njegov visoki stas, jer sam ga odbacio. Bog ne gleda kao što gleda čovjek: čovjek gleda na oči, a Jahve gleda što je u srcu.”"},{"v":8,"t":"Zatim Jišaj dozva Abinadaba i dovede ga pred Samuela. A on reče: “Ni ovoga Jahve nije izabrao.”"},{"v":9,"t":"Tada Jišaj dovede Šamu, ali Samuel reče: “Ni ovoga Jahve nije izabrao.”"},{"v":10,"t":"Tako Jišaj dovede sedam svojih sinova pred Samuela, ali Samuel reče Jišaju: “Jahve nije izabrao nijednoga od ovih.”"},{"v":11,"t":"Potom zapita Jišaja: “Jesu li to svi tvoji sinovi?” A on odgovori: “Ostao je još najmlađi, on je na paši, za stadom.” Tada Samuel reče Jišaju: “Pošalji po njega, jer nećemo sjedati za stol dok on ne dođe.”"},{"v":12,"t":"Jišaj posla po njega: bio je to rumen momak, lijepih očiju i krasna stasa. I Jahve reče Samuelu: “Ustani, pomaži ga: taj je!”"},{"v":13,"t":"Samuel uze rog s uljem i pomaza ga usred njegove braće. Duh Jahvin obuze Davida od onoga dana. A Samuel krenu na put i ode u Ramu."},{"v":14,"t":"Duh Jahvin bijaše odstupio od Šaula, a jedan zao duh, od Jahve, stao ga je salijetati."},{"v":15,"t":"Tada rekoše Šaulu sluge njegove: “Evo, zao duh Božji salijeće te."},{"v":16,"t":"Zato neka naš gospodar zapovjedi, pa će sluge tvoje potražiti čovjeka koji zna udarati u harfu: kad te napadne zao duh Božji, neka onaj udara u harfu pa će ti biti bolje.”"},{"v":17,"t":"Šaul reče svojim slugama: “Nađite mi čovjeka koji umije vješto udarati u harfu i dovedite ga k meni!”"},{"v":18,"t":"Jedan od njegovih slugu odgovori i reče: “Ja sam vidio jednog sina Betlehemca Jišaja: on umije udarati u harfu, hrabar je junak i čovjek ratnik, vješt je govornik, krasna je stasa i Jahve je s njim.”"},{"v":19,"t":"Tada Šaul posla glasnike k Jišaju i poruči mu: “Pošalji mi svoga sina Davida (koji je kod stada)!”"},{"v":20,"t":"A Jišaj uze pet hljebova, mijeh vina i jedno jare i posla Šaulu po svome sinu Davidu."},{"v":21,"t":"Tako David dođe k Šaulu i stupi u njegovu službu. I Šaul ga veoma zavolje i David posta njegov štitonoša."},{"v":22,"t":"Potom Šaul posla k Jišaju i poruči mu: “Neka David ostane kod mene u službi, jer je stekao moju naklonost.”"},{"v":23,"t":"I kad god bi Božji duh napao Šaula, David bi uzeo harfu i svirao; tada bi Šaulu odlanulo i bilo bi mu bolje, a zao bi duh odlazio od njega."}]},"17":{"hr":[{"v":1,"t":"Filistejci skupiše svoje čete za rat i sastaše se kod Soka u Judeji. Tabor udariše između Soka i Azeke kod Efes Damima."},{"v":2,"t":"A Šaul i Izraelci skupiše se i utaboriše u Terebintskoj dolini, i svrstaše se za boj protiv Filistejaca."},{"v":3,"t":"Filistejci su stajali na gori s jedne strane, Izraelci na gori s druge strane, a dolina bila među njima."},{"v":4,"t":"Iz filistejskih redova izađe jedan izazivač. Zvao se Golijat, a bio je iz Gata. Visok bijaše šest lakata i jedan pedalj."},{"v":5,"t":"Na glavi je imao mjedenu kacigu, obučen je bio u ljuskav oklop, a oklop mu težak pet tisuća mjedenih šekela."},{"v":6,"t":"Na nogama je imao mjedene nogavice, a na ramenima mjedenu sulicu."},{"v":7,"t":"Kopljača njegova koplja bila je kao tkalačko vratilo, a šiljak koplja težak šest stotina željeznih šekela. Pred njim je stupao štitonoša."},{"v":8,"t":"On se postavi pred izraelske bojne redove i dovikne im: “Što ste izašli da se svrstate za bitku? Nisam li ja Filistejac, a vi Šaulove sluge? Izaberite između sebe jednoga čovjeka pa neka siđe k meni!"},{"v":9,"t":"Ako pobijedi u borbi sa mnom i pogubi me, mi ćemo biti vaše sluge. Ako li ja pobijedim njega i pogubim ga, onda ćete vi biti naše sluge i nama ćete robovati.”"},{"v":10,"t":"Još je Filistejac rekao: “Ja sam danas izazvao Izraelove bojne redove. Dajte mi čovjeka da se ogledamo u dvoboju!”"},{"v":11,"t":"Kad je Šaul i sav Izrael čuo što je rekao Filistejac, obuze ih strah i drhat."},{"v":12,"t":"David je bio sin nekoga Efraćanina iz Betlehema u Judeji; taj se zvao Jišaj, a imao je osam sinova. Taj je čovjek u Šaulovo vrijeme bio star i odmakao u godinama."},{"v":13,"t":"Tri najstarija Jišajeva sina bijahu otišla u rat za Šaulom; a ta trojica njegovih sinova koji bijahu otišli u rat zvahu se: najstariji Eliab, drugi Abinadab, a treći Šama."},{"v":14,"t":"David bijaše najmlađi. A tri najstarija bijahu otišla za Šaulom. -"},{"v":15,"t":"David je odlazio k Šaulu i vraćao se iz njegove službe da pase stada svoga oca u Betlehemu."},{"v":16,"t":"A Filistejac izlazio svakoga jutra i večeri i postavljao se tako četrdeset dana. -"},{"v":17,"t":"A Jišaj reče svome sinu Davidu: “Uzmi za svoju braću ovu efu prženoga žita i ovih deset hljebova i odnesi brže svojoj braći u tabor."},{"v":18,"t":"A ovih deset sireva odnesi njihovu tisućniku. Propitaj se za zdravlje svoje braće i donesi od njih znak da si izvršio nalog!"},{"v":19,"t":"Oni su sa Šaulom i svim Izraelom u Terebintskoj dolini: vojuju protiv Filistejaca.”"},{"v":20,"t":"David ustade u rano jutro, ostavi stado jednom čuvaru, spremi se i ode kako mu bijaše zapovjedio Jišaj. U tabor je stigao kad je vojska izlazila u bojni red i dizala bojni poklik."},{"v":21,"t":"Izraelci i Filistejci svrstaše se u bojni red jedni prema drugima."},{"v":22,"t":"David ostavi svoje stvari čuvaru opreme pa otrča u bojni red. Došavši, zapita svoju braću za zdravlje."},{"v":23,"t":"Dok je s njima govorio, gle, onaj izazivač (zvao se Golijat, Filistejac iz Gata) iziđe iz filistejskih bojnih redova i ponovi iste riječi kao prije. I David ih je čuo."},{"v":24,"t":"A čim su Izraelci ugledali toga čovjeka, pobjegoše svi daleko od njega i strah ih uhvati."},{"v":25,"t":"Neki Izraelac reče: “Jeste li vidjeli onoga čovjeka što je izišao? A izišao je da izaziva Izraela. Tko njega pogubi, kralj će mu dati silno blago i dat će mu svoju kćer i oslobodit će od poreza njegov očinski dom u Izraelu.”"},{"v":26,"t":"Tada David zapita ljude koji stajahu oko njega: “Što će to dobiti čovjek koji ubije toga Filistejca i skine sramotu s Izraela? I tko je taj neobrezani Filistejac da izaziva bojne redove živoga Boga?”"},{"v":27,"t":"A narod mu odgovori istim riječima kao prije: “Eto to će dobiti čovjek koji ga pogubi.”"},{"v":28,"t":"A kad je Eliab, njegov najstariji brat, čuo kako se razgovara s ljudima, usplamtje gnjevom na Davida pa mu reče: “A što si ti došao ovamo? Kome si ostavio ono malo ovaca u pustinji? Znam ja tvoju drskost i zlobu tvoga srca: došao si da vidiš bitku!”"},{"v":29,"t":"A David odgovori: “A što sam učinio? Zar se ne smije ni riječ reći?”"},{"v":30,"t":"Tada se okrene od njega k drugome i zapita istim riječima kao prije. Narod mu odgovori isto kao prvi put."},{"v":31,"t":"Kad su ljudi čuli što je govorio David, jave to Šaulu, a on ga pozva preda se."},{"v":32,"t":"David reče Šaulu: “Neka nikome ne klone srce zbog onoga čovjeka! Tvoj će sluga izaći i borit će se s tim Filistejcem.”"},{"v":33,"t":"Ali Šaul odvrati Davidu: “Ne možeš ti izaći na toga Filistejca da se boriš s njim jer si ti još dijete, a on ratnik od svoje mladosti.”"},{"v":34,"t":"Ali David odgovori Šaulu: “Tvoj je sluga čuvao ovce svome ocu, pa kad bi došao lav ili medvjed te uhvatio ovcu iz stada,"},{"v":35,"t":"ja bih potrčao za njim, udario ga i istrgao mu ovcu iz ralja. A ako bi se on digao na me, uhvatio bih ga za grivu i udarao ga dok ga ne bih ubio."},{"v":36,"t":"I lava je i medvjeda tvoj sluga ubio, pa će i taj neobrezani Filistejac proći kao jedan od njih jer je izazvao bojne čete Boga živoga.”"},{"v":37,"t":"David još dometne: “Jahve koji me izbavio iz lavlje pandže i medvjeđe šape izbavit će me i iz ruku toga Filistejca.” Tada Šaul reče Davidu: “Idi i Jahve neka bude s tobom!”"},{"v":38,"t":"Šaul obuče Davida u svoju ratnu odoru, na glavu mu ustače mjedenu kacigu i stavi mu oklop."},{"v":39,"t":"Pripasa Davidu svoj mač preko odore, ali David uzalud pokuša hodati, jer ne bijaše navikao, pa reče Šaulu: “Ne mogu hodati u tome jer nisam navikao.” Zato sve skinu sa sebe."},{"v":40,"t":"David uze svoj štap u ruku, izabra u potoku pet glatkih kamenova i metnu ih u svoju pastirsku torbu, koja mu je služila kao torba za praćku, te s praćkom u ruci pođe prema Filistejcu."},{"v":41,"t":"A Filistejac se sve bliže primicao Davidu, dok je njegov štitonoša stupao pred njim."},{"v":42,"t":"A kad Filistejac pogleda i vidje Davida, prezre ga s njegove mladosti - bijaše David mladić, rumen, lijepa lica."},{"v":43,"t":"Zato Filistejac reče Davidu: “Zar sam ja pseto te ideš na me sa štapovima?” I uze proklinjati Davida svojim bogovima."},{"v":44,"t":"Zatim Filistejac reče Davidu: “Dođi k meni da dam tvoje meso pticama nebeskim i zvijerima zemaljskim!”"},{"v":45,"t":"A David odgovori Filistejcu: “Ti ideš na me mačem, kopljem i sulicom, a ja idem na te u ime Jahve Sebaota, Boga Izraelovih četa koje si ti izazvao."},{"v":46,"t":"Danas će te Jahve predati u moju ruku, ja ću te ubiti, skinut ću tvoju glavu i još ću danas tvoje mrtvo tijelo i mrtva tjelesa filistejske vojske dati pticama nebeskim i zvijerima zemaljskim. Sva će zemlja znati da ima Bog u Izraelu."},{"v":47,"t":"I sav će ovaj zbor znati da Jahve ne daje pobjedu mačem ni kopljem, jer je Jahve gospodar bitke i on vas predaje u naše ruke.”"},{"v":48,"t":"Kad se Filistejac približio i pošao prema Davidu, izađe David iz bojnih redova i krenu pred Filistejca."},{"v":49,"t":"David segnu rukom u torbu, izvadi iz nje kamen i hitnu ga iz praćke. I pogodi Filistejca u čelo; kamen mu se zabi u čelo i on pade ničice na zemlju."},{"v":50,"t":"Tako je David praćkom i kamenom nadjačao Filistejca: udario je Filistejca i ubio ga, a nije imao mača u ruci."},{"v":51,"t":"Zato David potrča i stade na Filistejca, zgrabi njegov mač, izvuče ga iz korica i pogubi Filistejca odsjekavši mu glavu. Kad Filistejci vidješe kako pogibe njihov junak, nagnuše u bijeg."},{"v":52,"t":"Tada ustadoše Izraelci i Judejci, digoše bojnu viku i potjeraše Filistejce do opkopa oko Gata i do gradskih vrata Ekrona; filistejski mrtvaci pokriše put od Šaarajima sve do Gata i do Ekrona."},{"v":53,"t":"Nato se Izraelci vratiše iz te žestoke potjere za Filistejcima i opljačkaše njihov tabor."},{"v":54,"t":"A David uze Filistejčevu glavu i odnese je u Jeruzalem, a oružje njegovo položi u svoj šator."},{"v":55,"t":"Kad je Šaul vidio Davida gdje izlazi pred Filistejca, upitao je svoga vojvodu Abnera: “Čiji je sin taj mladić, Abnere?” A Abner je odgovorio: “Tako mi tvoga života, kralju, ne znam!”"},{"v":56,"t":"A kralj mu reče: “Raspitaj se čiji je sin taj mladić!”"},{"v":57,"t":"A kad se David vratio pošto je pogubio Filistejca, uze ga Abner i dovede ga pred Šaula, a u ruci David još držaše Filistejčevu glavu."},{"v":58,"t":"Šaul ga upita: “Čiji si ti sin, momče?” A David odgovori: “Sin sam tvoga sluge Betlehemca Jišaja.”"}]},"18":{"hr":[{"v":1,"t":"Kad je David završio razgovor sa Šaulom, Jonatanova se duša prikloni Davidovoj duši i Jonatan ga zavolje kao samoga sebe."},{"v":2,"t":"Šaul zadrža Davida onoga istog dana kod sebe i nije mu dao da se vrati kući svoga oca."},{"v":3,"t":"I Jonatan sklopi savez s Davidom jer ga je ljubio kao samoga sebe."},{"v":4,"t":"I skide Jonatan plašt koji je imao na sebi i dade ga Davidu; tako i svoju odoru, čak i svoj mač, svoj luk i svoj pojas."},{"v":5,"t":"Na svim svojim pohodima, kamo ga je god slao Šaul, David bijaše sretne ruke i Šaul ga postavi na čelo svojim ratnicima; omilje on svemu narodu, pa i Šaulovim dvoranima."},{"v":6,"t":"Za njihova povratka, kad se David vraćao ubivši Filistejca, izađoše žene iz svih gradova Izraelovih u susret kralju Šaulu veselo kličući, pjevajući i plešući uza zvuke bubnjeva i cimbala."},{"v":7,"t":"Žene su plešući pjevale: “Pobi Šaul svoje tisuće, David na desetke tisuća.”"},{"v":8,"t":"Šaul se vrlo ražestio, nije mu bila draga ta pjesma. Zato reče: “Davidu su dale desetke tisuća, a meni samo tisuće! Još mu samo treba kraljevstvo!”"},{"v":9,"t":"I od toga dana Šaul poprijeko gledaše Davida."},{"v":10,"t":"Sutradan zao duh Božji napade Šaula, tako da je bjesnio po kući. David je rukom udarao u harfu kao drugih dana, a Šaul je u ruci imao koplje."},{"v":11,"t":"I Šaul baci koplje govoreći u sebi: “Sad ću pribiti Davida uza zid!” Ali mu se David izmače dva puta."},{"v":12,"t":"Šaul se poče bojati Davida, jer je Jahve bio s njim a od Šaula je odstupio."},{"v":13,"t":"Zato ga Šaul ukloni iz svoje blizine i postavi ga za tisućnika: on je izlazio i vraćao se na čelu naroda."},{"v":14,"t":"David je imao uspjeha na svim svojim putovima jer Jahve bijaše s njim."},{"v":15,"t":"Kad je Šaul vidio da David ima mnogo uspjeha, obuze ga strah od njega."},{"v":16,"t":"Ali svemu Izraelu i Judi omilje David jer ih je on vodio na svim njihovim putovima."},{"v":17,"t":"Šaul reče Davidu: “Evo svoju najstariju kćer Merabu dat ću ti za ženu, samo mi budi hrabar i vodi Jahvine bojeve!” Mišljaše Šaul: “Neću da padne od moje ruke, nego filistejska ruka neka se digne na njega!”"},{"v":18,"t":"A David odgovori: “Tko sam ja i što znači moj život, što li kuća oca mojega u Izraelu da budem kraljev zet?”"},{"v":19,"t":"I kad dođe vrijeme da Šaulova kći Meraba pođe za Davida, dadoše je za ženu Adrielu iz Mehole."},{"v":20,"t":"Ali je Davida ljubila Šaulova kći Mikala; kad su to javili Šaulu, bilo mu je pravo."},{"v":21,"t":"Reče on u sebi: “Dat ću mu je, ali će mu ona biti zamka i ruka filistejska dići će se na njega.” (Šaul je po drugi put rekao Davidu: “Danas ćeš mi biti zet.”)"},{"v":22,"t":"Tada Šaul zapovjedi svojim slugama ovako: “Razgovarajte se s Davidom tajno i recite mu: 'Gle, omilio si kralju i svi te njegovi dvorani vole; zato budi kraljev zet.'”"},{"v":23,"t":"I Šaulove sluge ponoviše te riječi Davidu, ali im David odgovori: “Zar je u vašim očima malenkost postati kraljev zet? Ja sam samo siromah i mali čovjek!”"},{"v":24,"t":"Šaulove sluge dojaviše to Šaulu govoreći: “Evo riječi što ih je rekao David.”"},{"v":25,"t":"A Šaul odgovori: “Ovako recite Davidu: 'Kralj ne traži nikakva ženidbenog dara nego samo sto filistejskih obrezaka da se osveti kraljevim neprijateljima.'” Šaul mišljaše da će tako Davida gurnuti u ruke Filistejcima."},{"v":26,"t":"Šaulove sluge dojaviše te riječi Davidu, a njemu bijaše po volji da postane kraljev zet. Još prije nego što je isteklo vrijeme,"},{"v":27,"t":"spremi se David i krenu sa svojim ljudima te ubi Filistejcima dvije stotine ljudi; i donese njihove obreske i predade ih kralju na broj da bi postao njegov zet. Tada mu Šaul dade svoju kćer Mikalu za ženu."},{"v":28,"t":"Šaul je jasno vidio da je Jahve s Davidom i da ga ljubi sav dom Izraelov."},{"v":29,"t":"I Šaul se još većma poboja Davida i posta neprijatelj Davidu zauvijek."},{"v":30,"t":"A filistejski su knezovi izlazili u boj, ali koliko su god puta izlazili, David je imao više uspjeha nego svi Šaulovi dvorani; i tako ime njegovo posta vrlo slavno."}]},"19":{"hr":[{"v":1,"t":"Šaul razloži svome sinu Jonatanu i svim svojim dvoranima svoju namjeru da ubije Davida. Ali Jonatan, Šaulov sin, vrlo je volio Davida."},{"v":2,"t":"I Jonatan to javi Davidu ovako: “Moj otac Šaul kani te ubiti. Budi, dakle, na oprezu sutra ujutro, ostani u skrovištu i pritaji se."},{"v":3,"t":"A ja ću izaći i stajat ću pokraj svoga oca u polju gdje ti budeš i govorit ću za tebe sa svojim ocem. Kad saznam kako je, javit ću ti.”"},{"v":4,"t":"Jonatan pohvali Davida svome ocu Šaulu i reče mu ovako: “Neka se kralj ne ogriješi o svoga slugu Davida jer se on nije ništa ogriješio o tebe; naprotiv, ono što je radio bilo je od velike koristi za tebe."},{"v":5,"t":"On je stavio život svoj na kocku, ubio je Filistejca i Jahve je pribavio veliku pobjedu svemu Izraelu: vidio si i radovao se. Zašto bi se, dakle, ogriješio o nevinu krv ubijajući Davida bez razloga?”"},{"v":6,"t":"Šaul posluša Jonatanove riječi i zakle se: “Živoga mi Jahve, David neće umrijeti!”"},{"v":7,"t":"Tada Jonatan dozva Davida i kaza mu sve te riječi. Zatim Jonatan dovede Davida k Šaulu i David opet dobi službu koju je imao prije."},{"v":8,"t":"Kad je rat i opet buknuo, iziđe David na bojište da se bori s Filistejcima; i porazi ih tako da su pobjegli pred njim."},{"v":9,"t":"Tada zao duh Jahvin obuze Šaula: kad je sjedio u svojoj kući, s kopljem u ruci, a David rukom udarao u harfu,"},{"v":10,"t":"Šaul pokuša da svojim kopljem pribode Davida uza zid, ali on izmakne Šaulovu udarcu te se koplje zabode u zid. David pobježe i spasi se."},{"v":11,"t":"Iste noći Šaul posla glasnike da nadziru Davidovu kuću jer je htio da ubije Davida u rano jutro. Ali Davidova žena Mikala javi to Davidu govoreći: “Ako noćas ne umakneš na sigurno mjesto, sutra ćeš biti mrtav!”"},{"v":12,"t":"Tada Mikala spusti Davida kroz prozor. On ode i spasi se bijegom."},{"v":13,"t":"A Mikala uze idol, položi ga u postelju, stavi mu oko glave kozju dlaku i pokri ga pokrivačem."},{"v":14,"t":"Kad je Šaul poslao glasnike da uhvate Davida, ona im reče: “Bolestan je.”"},{"v":15,"t":"Ali Šaul vrati glasnike natrag da vide Davida i zapovjedi im: “Donesite ga k meni u postelji da ga ubijem!”"},{"v":16,"t":"A kad su glasnici ušli, gle: u postelji bješe idol, s kozjom dlakom oko glave!"},{"v":17,"t":"Tada Šaul reče Mikali: “Zašto si me tako prevarila i pustila moga neprijatelja da pobjegne i da se spasi?” A Mikala odgovori Šaulu: “On mi je rekao: 'Pusti me da odem, ili ću te ubiti!'”"},{"v":18,"t":"Tako je David pobjegao i spasio se. I ode on k Samuelu u Ramu i javi mu sve što mu je učinio Šaul. Potom odoše on i Samuel i nastaniše se u Najotu."},{"v":19,"t":"A Šaulu javiše ovako: “Eno Davida u Najotu u Rami.”"},{"v":20,"t":"Tada Šaul posla glasnike da uhvate Davida. Kad su oni vidjeli zbor proroka u proročkom zanosu, a Samuela im na čelu, obuze Božji duh i Šaulove glasnike te i oni padoše u proročki zanos."},{"v":21,"t":"Kad su to javili Šaulu, on posla druge glasnike, ali i oni padoše u proročki zanos. Potom Šaul posla i treće glasnike, ali i oni padoše u proročki zanos."},{"v":22,"t":"Tada Šaul krenu sam u Ramu i kad dođe do velikog bunara kod Sekua, zapita: “Gdje su Samuel i David?” I odgovoriše mu: “Eno ih u Najotu u Rami.”"},{"v":23,"t":"On odmah pođe prema Najotu u Rami. Ali i njega obuze duh Božji te je išao u proročkom zanosu sve dok nije došao u Najot u Rami."},{"v":24,"t":"Tu i on svuče svoje haljine jer i njega obuze zanos pred Samuelom; zatim je legao gol i ostao tako cio onaj dan i svu noć. Tako je nastala uzrečica: “Zar je i Šaul među prorocima?”"}]},"20":{"hr":[{"v":1,"t":"David pobježe iz Najota u Rami i dođe k Jonatanu te mu reče: “Što sam učinio? Kakva je bila moja krivica i što sam zgriješio tvome ocu da traži moj život?”"},{"v":2,"t":"A on mu odgovori: “Daleko od tebe ta misao! Ti nećeš poginuti. Eto, moj otac ne poduzima ništa, bilo veliko ili ne bilo, a da to meni ne otkrije. Zašto bi, dakle, moj otac krio od mene upravo to? Neće to biti!”"},{"v":3,"t":"Ali se David zakle i reče: “Tvoj otac dobro zna da sam ja stekao tvoju naklonost, pa misli: 'Ne treba da Jonatan išta zna o tome, da ne bude žalostan.' Ali živoga mi Jahve i života mi tvoga, ima samo jedan korak između mene i smrti.”"},{"v":4,"t":"Tada Jonatan upita Davida: “Što želiš da učinim za tebe?”"},{"v":5,"t":"A David odgovori Jonatanu: “Evo, sutra je mladi mjesec i ja bih morao jesti s kraljem za stolom; ali me ti pusti da odem, da se sakrijem u polju do večera."},{"v":6,"t":"Ako tvoj otac opazi da me nema, reći ćeš mu ovako: 'David me uporno molio da ga pustim da skokne u svoj grad Betlehem, jer se ondje slavi godišnja žrtva za svu njegovu obitelj.'"},{"v":7,"t":"Ako on rekne: 'Dobro!', tvoj je sluga spašen. Ako li plane gnjevom, znaj da je čvrsto naumio da me pogubi."},{"v":8,"t":"Iskaži, dakle, milost svome sluzi kad si slugu svoga uveo sa sobom u savez Jahvin. Ali ako ima kakva krivica na meni, ubij me sam; zašto bi me vodio k svome ocu?”"},{"v":9,"t":"A Jonatan mu odgovori: “Daleko od tebe ta misao! Kad bih ja pouzdano znao da je moj otac čvrsto naumio da na tebe svali nesreću, zar ti ja ne bih dojavio?”"},{"v":10,"t":"David upita Jonatana: “A tko će mi javiti ako ti tvoj otac odgovori što zlo?”"},{"v":11,"t":"Jonatan odgovori Davidu: “Hodi, izađimo u polje!” I izađu obojica u polje."},{"v":12,"t":"Tada Jonatan reče Davidu: “Jahve, Bog Izraelov, neka mi bude svjedok! Ja ću iskušati svoga oca sutra u ovo doba. Ako bude dobro po Davida, a ja ne pošaljem k tebi da te obavijestim,"},{"v":13,"t":"neka Jahve učini to zlo Jonatanu i neka mu doda drugo zlo! Ako li mome ocu bude drago da ti učini zlo, javit ću ti i pustit ću te da odeš u miru; i Jahve neka bude s tobom kao što je bio s mojim ocem!"},{"v":14,"t":"Ako ja još budem živ, moći ćeš mi iskazati milosrđe Jahvino; ako li umrem,"},{"v":15,"t":"ne uskrati svoje dobrote mome domu dovijeka! Kad Jahve redom iskorijeni Davidove neprijatelje s lica zemlje,"},{"v":16,"t":"neka ime Jonatanovo ne iščezne s domom Šaulovim, inače će Jahve tražiti o tome račun od Davida.”"},{"v":17,"t":"Tada se Jonatan još jednom zakune Davidu ljubavlju svojom, jer ga je ljubio svom ljubavlju duše svoje."},{"v":18,"t":"Potom reče Jonatan Davidu: “Sutra je mladi mjesec i opazit će se da te nema, jer će tvoje mjesto biti prazno."},{"v":19,"t":"Prekosutra će se još očitije vidjeti da te nema, a ti dođi na mjesto gdje si se bio sakrio u dan onoga događaja i sjedni kraj onoga humka što ga znaš."},{"v":20,"t":"A ja ću prekosutra izmetati strijele na onu stranu kao da gađam onamo."},{"v":21,"t":"A onda ću poslati momka i reći mu: 'Idi! Nađi strijelu!' Ako onda doviknem momku: 'Pazi, strijela je ovamo bliže od tebe, donesi je!' - ti onda dođi, jer je za tebe dobro i nema nikakve opasnosti, tako mi Jahve živoga!"},{"v":22,"t":"Ako li doviknem momku: 'Pazi, strijela je onamo dalje od tebe!' - ti onda otiđi, jer te Jahve šalje odavde."},{"v":23,"t":"A za ovaj dogovor što smo ga ugovorili ja i ti neka je Jahve svjedok između mene i tebe dovijeka!”"},{"v":24,"t":"Potom se David sakri u polju. Kad je došao mlađak, kralj je sjeo za stol da jede."},{"v":25,"t":"Kralj sjede na svoje obično mjesto, na mjesto uza zid, Jonatan se smjesti sučelice njemu, Abner sjede kraj Šaula, a Davidovo mjesto osta prazno."},{"v":26,"t":"Ali Šaul ne reče ništa onaj dan jer mišljaše: “Dogodilo mu se štogod, bit će da nije čist.”"},{"v":27,"t":"Sutradan iza mladog mjeseca, drugi dan u mjesecu, opet Davidovo mjesto osta prazno, i Šaul upita svoga sina Jonatana: “Zašto Jišajev sin nije došao na objed ni jučer ni danas?”"},{"v":28,"t":"A Jonatan odgovori Šaulu: “David me uporno molio da ga pustim da ide u Betlehem."},{"v":29,"t":"Rekao mi je: 'Pusti me da idem jer slavimo obiteljsku žrtvu u mom gradu i moja su me braća pozvala da dođem. Ako sam, dakle, stekao tvoju naklonost, daj mi dopust da pohodim svoju braću.' Eto, zato ga nema kod kraljeva stola.”"},{"v":30,"t":"Tada Šaul planu gnjevom na Jonatana i reče mu: “Izrode i propalico! Misliš da ne znam da si u savezu s Jišajevim sinom, na sramotu svoju i na sramotu majčinu krilu!"},{"v":31,"t":"Jer dokle god bude živ na zemlji Jišajev sin, nećeš biti siguran ni ti ni tvoje kraljevstvo. Zato sad pošalji po njega i dovedi ga k meni jer je osuđen na smrt.”"},{"v":32,"t":"A Jonatan odvrati svome ocu Šaulu i reče mu: “Zašto on mora umrijeti? Što je učinio?”"},{"v":33,"t":"Tada Šaul izmetnu koplje na sina da ga probode. Jonatan vidje da je njegov otac odlučio da ubije Davida."},{"v":34,"t":"Jonatan ustade od stola sav jarostan i nije jeo ništa toga drugog dana u mjesecu jer se zabrinuo za Davida što ga je njegov otac pogrdio."},{"v":35,"t":"Sutradan ujutro izađe Jonatan u polje prema dogovoru s Davidom; s njim je išao mlad momak."},{"v":36,"t":"I on reče svome momku: “Ti ćeš otrčati i naći strijele koje ću sada izmetnuti.” I momak otrča, a Jonatan odape strijelu tako da je preletjela preko njega."},{"v":37,"t":"Kad je momak došao do mjesta gdje je bila strijela koju je izbacio Jonatan, viknu Jonatan za momkom: “Nije li strijela onamo dalje od tebe?”"},{"v":38,"t":"Još Jonatan viknu za momkom: “Brže! Požuri se! Ne stoj!” Jonatanov momak diže strijelu i donese je svome gospodaru."},{"v":39,"t":"Momak nije ništa opazio, samo su Jonatan i David znali o čemu se radi."},{"v":40,"t":"Nato Jonatan preda oružje momku i reče mu: “Idi i odnesi to u grad!”"},{"v":41,"t":"Kad je momak otišao, David iziđe iza humka, pade ničice na zemlju i pokloni se tri puta. Potom se izljubiše i plakahu zajedno dok se nisu isplakali."},{"v":42,"t":"Zatim Jonatan reče Davidu: “Idi u miru! Što smo se obojica zakleli Jahvinim imenom, neka Jahve bude svjedok između mene i tebe, između moga potomstva i tvoga potomstva dovijeka!”"}]},"21":{"hr":[{"v":1,"t":"Nato David usta i ode, a Jonatan se vrati u grad."},{"v":2,"t":"David dođe u Nob k svećeniku Ahimeleku. Ovaj dršćući pođe u susret Davidu i upita ga: “Zašto si sam i nema nikoga s tobom?”"},{"v":3,"t":"A David odgovori svećeniku Ahimeleku: “Kralj mi je dao nalog i rekao mi: 'Nitko neka ništa ne dozna zašto te šaljem i što sam ti zapovjedio!' A momke sam poslao da me dočekaju na tom i tom mjestu."},{"v":4,"t":"A sada, ako imaš pri ruci pet hljebova, daj mi ih, ili što god se nađe!”"},{"v":5,"t":"A svećenik odgovori Davidu: “Nemam pri ruci običnoga kruha nego samo svetoga kruha; ali samo ako su se tvoji momci uzdržali od žena.”"},{"v":6,"t":"David odgovori svećeniku ovako: “Sasvim pouzdano! Žene su nam bile uskraćene, kao uvijek kad izlazimo na vojni pohod, i tijela su u momaka čista. Iako je ovo običan put, uistinu su danas čisti tijelom.”"},{"v":7,"t":"Tada mu svećenik dade svetoga kruha, jer nije bilo drugoga kruha ondje osim žrtvenoga, onoga koji se uklanjao ispred Jahve da se zamijeni toplim kruhom u dan kad se uzima."},{"v":8,"t":"Ondje je istoga dana bio jedan od Šaulovih slugu, zadržao se pred Jahvom; zvao se Doeg Edomac, a bio je nadglednik Šaulovih pastira."},{"v":9,"t":"David upita Ahimeleka: “A nemaš li ovdje pri ruci kakvo koplje ili mač? Nisam uzeo sa sobom ni svoga mača ni svoga oružja, jer je kraljev nalog bio hitan.”"},{"v":10,"t":"A svećenik mu odgovori: “Ovdje je mač Filistejca Golijata, onoga koga si ubio u Terebintskoj dolini; zamotan je u plašt i položen iza oplećka; ako ga hoćeš uzeti, uzmi ga samo, jer drugoga osim njega nema ovdje.” A David odvrati: “Takva više nema, daj mi ga!”"},{"v":11,"t":"Potom David ustade i pobježe onaj dan daleko od Šaula i dođe Akišu, kralju Gata."},{"v":12,"t":"A dvorani Akiševi rekoše svome kralju: “Nije li to David, kralj zemlje? To je onaj o kome su plešući pjevali: 'Pobi Šaul svoje tisuće, David na desetke tisuća.'”"},{"v":13,"t":"David se zamisli o tim riječima i silno se uplaši gatskoga kralja Akiša."},{"v":14,"t":"Tada se David poče pretvarati pred njima kao da je umobolan i vladati se kao luđak u njihovim rukama: bubnjao je po vratima i puštao da mu teče slina niz bradu."},{"v":15,"t":"Tada Akiš reče svojim dvoranima: “Vidite dobro da je čovjek lud! Zašto ga dovodite k meni?"},{"v":16,"t":"Zar nemam dosta budala te mi dovodite ovoga da mi dosađuje svojim ludilom? Zar će taj ući u moju kuću?”"}]},"22":{"hr":[{"v":1,"t":"David ode odande i skloni se u spilju Adulam. A kad su to čula njegova braća i sva njegova obitelj, dođoše onamo da mu se priključe."},{"v":2,"t":"Osim toga skupiše se oko njega svi koji bijahu u nevolji, svi zaduženi, svi nezadovoljni, i on im posta vođom. A bijaše ih oko njega do četiri stotine ljudi."},{"v":3,"t":"Odande ode David u Mispu u zemlji moapskoj i reče kralju moapskome: “Dopusti da se moj otac i moja mati sklonu kod vas dok ne vidim što će Bog učiniti sa mnom.”"},{"v":4,"t":"I ostavi ih kod kralja moapskoga i oni ostadoše kod njega sve dok David bijaše u skrovištu."},{"v":5,"t":"Ali prorok Gad reče Davidu: “Nemoj ostati u svome skrovištu, nego idi i zađi u zemlju Judinu.” I David ode i zađe u Heretsku šumu."},{"v":6,"t":"Šaul doznade da se pojavio David s ljudima koji bijahu s njim. Šaul je upravo bio u Gibei; sjedio je pod tamariskom na uzvišici, s kopljem u ruci, a oko njega stajali svi njegovi dvorani."},{"v":7,"t":"I reče Šaul svojim dvoranima koji stajahu oko njega: “Poslušajte me, sinovi Benjaminovi! Hoće li vam i Jišajev sin svima darovati njive i vinograde? Hoće li vas sve postaviti za tisućnike i stotnike?"},{"v":8,"t":"A zašto ste se onda svi urotili protiv mene? Nema nikoga da mi dojavi kad moj sin sklapa savez s Jišajevim sinom, nema nikoga među vama da me požali i da mi otkrije kako je moj sin podjario moga slugu na me, kao što se događa danas.”"},{"v":9,"t":"Tada progovori Doeg Edomac, koji je stajao među Šaulovim dvoranima, i reče: “Ja sam vidio Jišajeva sina kad je došao u Nob k Ahimeleku, Ahitubovu sinu."},{"v":10,"t":"Ovaj je zatražio za njega savjet od Jahve i dao mu hrane i predao mu mač Filistejca Golijata.”"},{"v":11,"t":"Šaul nato zapovjedi da pozovu svećenika Ahimeleka, Ahitubova sina, i svu njegovu obitelj, svećenike u Nobu. I dođoše svi pred kralja."},{"v":12,"t":"Tada reče Šaul: “Čuj me, Ahitubov sine!” A on odgovori: “Evo me, gospodaru!”"},{"v":13,"t":"A Šaul ga upita: “Zašto ste se urotili protiv mene, ti i Jišajev sin? Ti si mu dao kruha i mač i tražio si za njega savjet od Boga da se digne protiv mene kao neprijatelj, kao što se danas događa.”"},{"v":14,"t":"Ahimelek odgovori kralju: “A tko je među svim tvojim slugama ravan Davidu, tako vjeran, uz to kraljev zet, glavar tvoje tjelesne straže, čovjek koji je poštovan u tvojoj kući?"},{"v":15,"t":"Zar sam danas prvi put tražio za njega savjet od Boga? Daleko od mene svaka druga misao! Neka kralj ništa ne okrivljuje svoga sluge i sve njegove obitelji, jer sluga njegov nije znao od svega toga ništa!”"},{"v":16,"t":"Ali kralj odvrati: “Ti ćeš umrijeti, Ahimeleče, ti i sva tvoja obitelj!”"},{"v":17,"t":"I kralj zapovjedi glasonošama koji stajahu oko njega: “Pristupite i pogubite svećenike Jahvine jer su i oni pomogli Davidu: znali su da je na bijegu, a nisu mi to dojavili.” Ali kraljevi stražari ne htjedoše dići ruke na Jahvine svećenike da ih smaknu."},{"v":18,"t":"Tada kralj zapovjedi Doegu: “Pristupi ti i smakni svećenike!” Doeg Edomac pristupi i smaknu svećenike: on pogubi u onaj dan osamdeset i pet ljudi koji su nosili laneni oplećak."},{"v":19,"t":"I Nob, svećenički grad, pohara oštricom mača, pobivši muškarce i žene, djecu i dojenčad, goveda, magarce i ovce."},{"v":20,"t":"Izbavio se samo jedan sin Ahimeleka, Ahitubova sina, po imenu Ebjatar i pobjegao k Davidu."},{"v":21,"t":"Ebjatar javi Davidu da je Šaul poklao Jahvine svećenike."},{"v":22,"t":"A David odvrati Ebjataru: “Ja sam već onoga dana kad ondje bijaše Doeg Edomac znao da će on zacijelo javiti to Šaulu! Ja sam kriv za živote tvoga očinskog doma."},{"v":23,"t":"Ostani kod mene, ne boj se: tko bude tražio tvoj život, tražit će moj. Kod mene ćeš biti dobro čuvan.”"}]},"23":{"hr":[{"v":1,"t":"Javiše onda Davidu: “Filistejci opsjedaju Keilu i pljačkaju gumna.”"},{"v":2,"t":"David tada upita Jahvu: “Treba li da idem na Filistejce i hoću li ih potući?” A Jahve odgovori Davidu: “Idi, potući ćeš Filistejce i oslobodit ćeš Keilu.”"},{"v":3,"t":"Ali rekoše Davidu ljudi njegovi: “Gle, mi smo već ovdje, u Judi, u neprestanom strahu; što će tek biti ako odemo u Keilu protiv filistejskih četa!”"},{"v":4,"t":"Zato David još jednom upita Jahvu, a Jahve mu odgovori ovako: “Ustani i siđi u Keilu jer ću predati Filistejce u tvoje ruke!”"},{"v":5,"t":"David onda krenu sa svojim ljudima u Keilu, udari na Filistejce, otjera njihovu stoku i zada im težak poraz. Tako je David oslobodio građane Keile. -"},{"v":6,"t":"Kad je ono Ebjatar, Ahimelekov sin, pobjegao k Davidu, on je došao u Keilu noseći u ruci oplećak."},{"v":7,"t":"Kad su Šaulu javili da je David ušao u Keilu, reče Šaul: “Bog ga je predao u moje ruke jer se sam uhvatio u zamku kad je ušao u grad s vratima i prijevornicama.”"},{"v":8,"t":"I Šaul sazva sav narod na oružje da ide na Keilu i da opkoli Davida i njegove ljude."},{"v":9,"t":"Kad je David doznao da mu Šaul snuje zlo, reče svećeniku Ebjataru: “Donesi oplećak!”"},{"v":10,"t":"Nato se David pomoli: “Jahve, Bože Izraelov, tvoj je sluga čuo da Šaul sprema navalu na Keilu da razori grad zbog mene."},{"v":11,"t":"Hoće li Šaul doći kao što je tvoj sluga čuo? Jahve, Bože Izraelov, odgovori svome sluzi!” A Jahve odgovori: “Doći će!”"},{"v":12,"t":"David opet upita: “Hoće li me prvaci Keile predati, mene i moje ljude, u Šaulove ruke?” A Jahve odgovori: “Predat će vas!”"},{"v":13,"t":"Tada David ustade sa svojim ljudima, bijaše ih oko šest stotina; iziđoše iz Keile te lutahu kojekuda. A kad su Šaulu javili da je David utekao iz Keile, odusta od vojnog pohoda."},{"v":14,"t":"David se skloni u pustinju u gorska skloništa; nastani se na gori u pustinji Zifu. Šaul ga je neprestano tražio, ali ga Bog ne predade u njegove ruke."},{"v":15,"t":"David se bojao što je Šaul izišao na vojnu da napadne na njegov život. Zato je David ostao u pustinji Zifu, u Horši."},{"v":16,"t":"Tada Šaulov sin Jonatan krenu na put i dođe k Davidu u Horšu i ohrabri ga u ime Božje."},{"v":17,"t":"Reče mu: “Ne boj se, jer te neće stići ruka moga oca Šaula. Ti ćeš kraljevati nad Izraelom, a ja ću biti drugi do tebe; i moj otac Šaul zna to dobro.”"},{"v":18,"t":"I sklopiše njih dvojica savez pred Jahvom. David osta u Horši, a Jonatan ode svojoj kući."},{"v":19,"t":"Jednoga dana dođoše Zifejci k Šaulu u Gibeu i javiše mu: “David se krije kod nas u gorskim skloništima u Horši, na brdu Hakili, što je južno od Ješimona."},{"v":20,"t":"Sada, kralju, kad god zaželiš sići, siđi, a naše je da ga predamo u ruke kralju.”"},{"v":21,"t":"A Šaul odgovori: “Blagoslovio vas Jahve što ste me požalili!"},{"v":22,"t":"Idite, dakle, raspitajte se još i dobro razvidite mjesto kamo ga donesu njegovi hitri koraci; rekli su mi da je vrlo lukav."},{"v":23,"t":"Zato pretražite sve rupe u koje se zavlači, pa se vratite k meni kad budete pouzdano znali. Tada ću ja poći s vama, pa ako bude gdje u zemlji, ići ću za njegovim tragom po svim Judinim rodovima.”"},{"v":24,"t":"Tada krenuše na put i odoše u Zif, pred Šaulom. David je sa svojim ljudima bio u pustinji Maonu u Arabi, južno od Ješimona."},{"v":25,"t":"Potom i Šaul pođe sa svojim ljudima da traži Davida. Kad su to javili Davidu, siđe on u klanac koji leži u pustinji Maonu. Šaul to doznade i krenu u potjeru za Davidom u pustinju Maon."},{"v":26,"t":"Šaul je sa svojim ljudima išao jednom stranom planine, a David sa svojim ljudima drugom stranom planine. David se silno žurio da umakne Šaulu. Kad je Šaul sa svojim ljudima htio prijeći na drugu stranu da opkoli Davida i njegove ljude i da ih pohvata,"},{"v":27,"t":"dođe glasnik Šaulu s porukom: “Dođi brže, Filistejci provališe u zemlju!”"},{"v":28,"t":"Tada Šaul odusta od potjere za Davidom i okrenu se protiv Filistejaca. Zato se prozvalo ono mjesto “Klanac razlaza”."}]},"24":{"hr":[{"v":1,"t":"David se odande uspe i nastani u engadskim gorskim skloništima."},{"v":2,"t":"Kad se Šaul vratio iz potjere za Filistejcima, javiše mu ovo: “David je u Engadskoj pustinji!”"},{"v":3,"t":"Tada Šaul uze tri tisuće odabranih ljudi iz svega Izraela i pođe da traži Davida i njegove ljude na istok od Litica divokoza."},{"v":4,"t":"Idući dođe k ovčjim torovima pokraj puta; ondje bijaše pećina i Šaul uđe da čučne; a David je sa svojim ljudima sjedio u dnu pećine."},{"v":5,"t":"I rekoše Davidu ljudi njegovi: “Evo dana za koji ti je rekao Jahve: 'Ja ću predati tvoga neprijatelja u tvoje ruke, postupaj s njim kako ti se mili!'” A David ustade i neprimjetno odsiječe skut od Šaulova plašta."},{"v":6,"t":"Ali poslije zapeče Davida savjest što je odsjekao skut od Šaulova plašta,"},{"v":7,"t":"pa reče svojim ljudima: “Očuvao me Jahve da takvo što učinim svome gospodaru, da dignem ruku na njega, jer je pomazanik Jahvin.”"},{"v":8,"t":"I David oštrim riječima ukori svoje ljude i ne dopusti im da ustanu na Šaula. A Šaul izađe iz pećine i pođe svojim putem."},{"v":9,"t":"Zatim ustade David, iziđe iz pećine i vikne za Šaulom: “Gospodaru kralju!” A kad se Šaul obazre, David se baci ničice na zemlju i pokloni mu se."},{"v":10,"t":"Tada David reče Šaulu: “Zašto slušaš ljude koji ti govore da David snuje tebi propast?"},{"v":11,"t":"Gle, upravo u ovaj dan tvoje su oči mogle vidjeti da te Jahve predao danas u moje ruke u ovoj pećini. Rekoše mi da te ubijem, ali te poštedjeh i rekoh: 'Neću dići svoje ruke na svoga gospodara, jer je Jahvin pomazanik.'"},{"v":12,"t":"O, moj oče, pogledaj i vidi skut od svoga plašta u mojoj ruci: odsjekao sam skut od tvoga plašta, a tebe nisam ubio; spoznaj i vidi da u mojoj ruci nema ni zlobe ni opačine. Ja nisam zgriješio protiv tebe, a ti vrebaš na moj život da mi ga uzmeš!"},{"v":13,"t":"Jahve neka sudi između mene i tebe, Jahve neka me osveti na tebi, ali se moja ruka neće dići na tebe."},{"v":14,"t":"Kako kaže stara poslovica: od nepravednika dolazi nepravda, i zato se moja ruka neće dići protiv tebe."},{"v":15,"t":"Za kim je izišao izraelski kralj? Za kim ideš u potjeru? Za mrtvim psom, za običnom buhom!"},{"v":16,"t":"Jahve neka bude sudac, on neka sudi između mene i tebe, neka ispita i brani moju stvar i neka mi pribavi pravdu: neka me izbavi iz tvoje ruke!”"},{"v":17,"t":"Kad je David izgovorio te riječi Šaulu, odvrati Šaul: “Je li to tvoj glas, sine Davide?” I Šaul glasno zaplaka."},{"v":18,"t":"Zatim reče Davidu: “Pravedniji si od mene jer ti si meni učinio dobro, a ja sam tebi učinio zlo."},{"v":19,"t":"A danas si okrunio svoju dobrotu prema meni, jer me Jahve predao u tvoje ruke, a ti me nisi ubio."},{"v":20,"t":"Kad se čovjek namjeri na svoga neprijatelja, pušta li ga da ide mirno svojim putem? Neka ti Jahve naplati za ono dobro što si mi danas učinio!"},{"v":21,"t":"Sada pouzdano znam da ćeš zacijelo biti kralj i da će se kraljevstvo nad Izraelom trajno održati u tvojoj ruci."},{"v":22,"t":"Zato mi se sada zakuni Jahvom da nećeš zatrti moga potomstva poslije mene i da nećeš izbrisati moga imena iz moga očinskoga doma!”"},{"v":23,"t":"David se zakle Šaulu, Šaul ode svojoj kući, a David se sa svojim ljudima vrati u gorska skloništa."}]},"25":{"hr":[{"v":1,"t":"Uto umrije Samuel. Sav se Izrael skupi i oplaka ga naričući za njim; i pokopaše ga u njegovu zavičaju u Rami. A David usta i siđe u pustinju Paran."},{"v":2,"t":"U Maonu živio čovjek koji je imao svoje gospodarstvo u Karmelu; bio je to vrlo bogat čovjek, imao je tri tisuće ovaca i tisuću koza. Upravo je tada strigao svoje ovce u Karmelu."},{"v":3,"t":"Taj se čovjek zvao Nabal, a njegova žena Abigajila. Žena je bila mudra i vrlo lijepa, a čovjek surov i opak: bio je Kalebovac."},{"v":4,"t":"David je u pustinji čuo da Nabal striže svoje ovce."},{"v":5,"t":"Stoga posla deset momaka naloživši im: “Idite gore u Karmel, otiđite k Nabalu i pozdravite ga u moje ime."},{"v":6,"t":"I recite ovako mome bratu: 'Mir tebi, mir tvome domu, mir svemu što imaš!"},{"v":7,"t":"Sada, čujem, strižeš ovce. A tvoji su pastiri bili kod nas, nismo ih dirali, ništa im nije nestalo dokle god su bili u Karmelu."},{"v":8,"t":"Pitaj svoje sluge i kazat će ti. Zato neka ovi momci nađu milost pred tobom, jer smo došli u svečan dan. Podaj svojim slugama i svome sinu Davidu što ti se nađe pri ruci.'”"},{"v":9,"t":"Dođoše momci Davidovi i ponoviše Nabalu u Davidovo ime sve ove riječi, a onda pričekaše."},{"v":10,"t":"Ali Nabal odgovori Davidovim slugama ovako: “Tko je David, tko je Jišajev sin? Danas ima mnogo slugu koji su pobjegli od svojih gospodara."},{"v":11,"t":"Zar da uzmem svoj kruh, svoju vodu, svoju stoku koju sam poklao za svoje strigače pa da to poklonim ljudima o kojima ne znam ni odakle su?”"},{"v":12,"t":"Davidovi se momci okrenuše i vratiše se svojim putem. Kad su se vratili, javiše sve ove riječi Davidu."},{"v":13,"t":"A David reče svojim ljudima: “Pripašite svaki svoj mač!” I pripasaše svaki svoj mač, i David pripasa svoj, i oko četiri stotine ljudi krenu za Davidom, dok ih dvije stotine osta kod tovara."},{"v":14,"t":"A ženi Nabalovoj, Abigajili, javio jedan od Nabalovih slugu ovo: “Eto, David je poslao iz pustinje glasnike da pozdrave našega gospodara, a on ih potjerao."},{"v":15,"t":"A ti su ljudi bili vrlo dobri prema nama: nisu nas dirali, ništa nismo izgubili dokle god smo bili u njihovoj blizini kad smo bili u polju."},{"v":16,"t":"Noću i danju bili su nam kao bedem u sve vrijeme dok smo bili s njima pasući stada."},{"v":17,"t":"Razmisli sada i vidi što ćeš učiniti, jer je gotova pogibija našem gospodaru i svemu njegovu domu; a on je opak čovjek komu se ne može ništa kazati.”"},{"v":18,"t":"Abigajila brzo uze dvije stotine hljebova, dva mijeha vina, pet zgotovljenih ovaca, pet mjera pržena žita, sto grozdova suhoga grožđa, dvije stotine smokovih kolača i sve to natovari na magarce."},{"v":19,"t":"I zapovjedi svojim slugama: “Idite preda mnom, a ja ću za vama.” Svome mužu Nabalu nije kazala ništa."},{"v":20,"t":"Dok je, jašući na magarcu, silazila iza gorskog zavoja, David je sa svojim ljudima silazio nasuprot njoj, tako da se ona susrela s njima."},{"v":21,"t":"A David je upravo mislio: “Uzalud sam, dakle, zaštićivao u pustinji sve što je taj čovjek imao i ništa mu nije nestalo od svega što je posjedovao! Sada mi vraća zlo za dobro!"},{"v":22,"t":"Neka Bog učini Davidu ovo zlo i neka mu doda drugo ako Nabalu do zore od svega što ima ostavim i ono što mokri uza zid!”"},{"v":23,"t":"Kad je Abigajila ugledala Davida, brzo sjaha s magarca i pade pred Davida ničice, poklonivši se do zemlje."},{"v":24,"t":"Bacivši mu se tako pred noge, reče: “Gospodaru, neka na mene padne krivica! Dopusti da službenica tvoja progovori tvojim ušima i udostoj se poslušati riječi službenice svoje!"},{"v":25,"t":"Neka moj gospodar ne gleda na toga opakog čovjeka, na Nabala, jer on s pravom nosi svoje ime: zove se Luda i ludost je s njim. A ja, službenica tvoja, nisam vidjela momaka koje je poslao moj gospodar."},{"v":26,"t":"Zato sada, gospodaru, živoga mi Jahve, i tako živ bio ti, i tako ti Jahve koji te očuvao da ne svališ na se krvnu krivicu i da ne pribaviš sebi pravdu svojom rukom: neka prođu kao Nabal tvoji neprijatelji i oni koji snuju zlo mome gospodaru!"},{"v":27,"t":"A ovaj dar, što ga evo tvoja službenica nosi svome gospodaru, neka se dade momcima koji idu za mojim gospodarom na njegovim putovima."},{"v":28,"t":"Oprosti službenici svojoj njezinu krivnju! Zacijelo će Jahve osnovati trajan dom mome gospodaru, jer moj gospodar bije Jahvine bojeve i za svega tvoga života neće se naći zlo na tebi."},{"v":29,"t":"Ako se tko digne da te progoni i da ti radi o glavi, neka život moga gospodara bude pohranjen u škrinji života kod Jahve, tvoga Boga, a život tvojih neprijatelja neka on baci kao iz praćke."},{"v":30,"t":"I kad Jahve učini mome gospodaru svako dobro koje ti je obećao i kad te odredi da budeš knezom nad Izraelom,"},{"v":31,"t":"onda neka ne bude na smutnju ni na grižnju savjesti mome gospodaru da je ni za što prolio krv i da je sebi pribavio pravdu svojoj rukom. I kad Jahve učini dobro mome gospodaru, sjeti se tada službenice svoje!”"},{"v":32,"t":"David odgovori Abigajili: “Neka je blagoslovljen Jahve, Bog Izraelov, koji te danas poslao meni u susret!"},{"v":33,"t":"Neka je blagoslovljena tvoja mudrost i blagoslovljena bila ti što si me danas zadržala da ne svalim na se krvnu krivicu i da ne pribavim sebi pravdu svojom rukom."},{"v":34,"t":"Ali, tako mi živog Jahve, Boga Izraelova, koji nije dopustio da ti učinim zlo: da mi nisi tako brzo izišla u susret, zaista ne bi Nabalu do jutra ostalo ni ono što uza zid mokri!”"},{"v":35,"t":"Nato David primi iz njezine ruke što mu bijaše donijela i reče joj: “Vrati se s mirom svojoj kući. Gle, uslišao sam tvoj glas i obazreo se na tebe.”"},{"v":36,"t":"Kad se Abigajila vratila k Nabalu, on je upravo imao gozbu u kući, pravu kraljevsku gozbu: Nabal bijaše veseo i sasvim pijan; zato mu ona ne reče ništa dok nije svanulo jutro."},{"v":37,"t":"A ujutro, kad se Nabal otrijeznio, pripovjedi mu njegova žena sve što se dogodilo, a njemu obamrije srce u grudima i on osta kao da se skamenio."},{"v":38,"t":"A desetak dana poslije toga Jahve udari Nabala te umrije."},{"v":39,"t":"Kad David ču da je umro Nabal, reče: “Neka je blagoslovljen Jahve, koji mi je ispravio nepravdu što mi je učini Nabal; i Jahve je očuvao svoga slugu da ne učini zla, a svalio je Nabalovu zloću na njegovu glavu!” Potom David posla poruku Abigajili da će je uzeti za ženu."},{"v":40,"t":"Davidove sluge dođoše k Abigajili u Karmel i rekoše joj: “David nas je poslao k tebi da te uzme sebi za ženu.”"},{"v":41,"t":"A ona ustade, pokloni se do zemlje i reče: “Evo službenice tvoje koja je spremna da bude robinja i da pere noge slugama svoga gospodara!”"},{"v":42,"t":"Potom Abigajila brzo ustade i zajaha na magarca, a za njom pođe pet njezinih dvorkinja. Tako je otišla za Davidovim poslanicima i postala njegovom ženom."},{"v":43,"t":"I Ahinoamom iz Jizreela bijaše se oženio David i obje mu bjehu žene."},{"v":44,"t":"Jer Šaul bijaše svoju kćer Mikalu, Davidovu ženu, dao Paltiju, sinu Lajiša iz Galima."}]},"26":{"hr":[{"v":1,"t":"Ljudi iz Zifa dođoše Šaulu i javiše mu: “David se krije na Hakilskom brdu, nasuprot Ješimonu.”"},{"v":2,"t":"Šaul tada krenu na put i siđe u pustinju Zif, a s njim tri tisuće izabranih Izraelaca, da traži Davida u pustinji Zifu."},{"v":3,"t":"Šaul se utabori podno Hakilskog brda, koje je nasuprot Ješimonu, kraj puta. David, koji je boravio u pustinji, opazi da je Šaul došao onamo da ga progoni."},{"v":4,"t":"Zato David posla uhode i sazna da je Šaul zaista došao."},{"v":5,"t":"David se podiže i dođe do mjesta gdje se Šaul bio utaborio. Tu David ugleda mjesto gdje su spavali Šaul i Abner, sin Nerov, njegov vojvoda: Šaul je spavao usred tabora, a vojska ležala u krugu oko njega."},{"v":6,"t":"David se obrati Hetitu Ahimeleku i Abišaju, sinu Sarvijinu a bratu Joabovu, i reče im: “Tko će sa mnom u tabor sve do Šaula?” A Abišaj odgovori: “Ja ću s tobom.”"},{"v":7,"t":"I tako David i Abišaj dopriješe noću do vojske: i gle, Šaul ležaše i spavaše u taboru, a koplje mu kod uzglavlja zabodeno u zemlju. Abner i vojnici ležahu oko njega."},{"v":8,"t":"Tada Abišaj reče Davidu: “Danas ti je Bog predao tvoga neprijatelja u tvoje ruke; zato sada dopusti da ga njegovim vlastitim kopljem pribodem za zemlju, jednim jedinim udarcem, drugoga mi neće trebati.”"},{"v":9,"t":"Ali David odgovori Abišaju: “Nemoj ga ubijati! Jer tko će dignuti ruku svoju na Jahvina pomazanika i ostati nekažnjen?”"},{"v":10,"t":"Još nastavi David: “Živoga mi Jahve, i udarit će ga Jahve, bilo da će mu doći njegov dan da umre, bilo da će otići u boj i poginuti."},{"v":11,"t":"Ne dao mi Jahve da dignem ruku na pomazanika Jahvina! Nego uzmi sada koplje što mu je kod uzglavlja i vrč za vodu, pa hajdemo!”"},{"v":12,"t":"I uze David koplje i vrč za vodu što su bili kod Šaulova uzglavlja i oni odoše: nitko nije ništa vidio ni opazio, nitko se nije probudio, nego su svi spavali jer bijaše na njih pao dubok san od Jahve."},{"v":13,"t":"David prijeđe na drugu stranu i stade na vrh gore u nekoj daljini, tako da je među njima bio velik prostor."},{"v":14,"t":"Tada viknu vojsci i Abneru, Nerovu sinu, ovako: “Zar se nećeš odazvati, Abnere?” A Abner se odazva i upita: “Tko si ti što uznemiruješ kralja?”"},{"v":15,"t":"A David odgovori Abneru: “Nisi li ti junak? I tko ti je ravan u Izraelu? Pa zašto onda nisi čuvao kralja, svoga gospodara? Jedan je od ratnika sišao do vas da ubije kralja, tvoga gospodara."},{"v":16,"t":"Nije lijepo to što si učinio. Tako mi živog Jahve, zaslužili ste smrt što niste čuvali svoga gospodara, pomazanika Jahvina. Pogledaj sada gdje je kraljevo koplje i gdje je vrč za vodu što mu bijaše do uzglavlja!”"},{"v":17,"t":"Tada Šaul poznade Davidov glas i upita: “Je li to tvoj glas, sine Davide?” A David odgovori: “Jest, kralju gospodaru!”"},{"v":18,"t":"I nastavi: “Zašto moj gospodar progoni svoga slugu? Što sam učinio? Kakva je krivica u mojoj ruci?"},{"v":19,"t":"Zato neka se sada moj gospodar i kralj udostoji poslušati riječi svoga sluge: ako te Jahve diže protiv mene, neka se prinosnicom ublaži; ako li to čine sinovi ljudski, neka su prokleti pred Jahvom jer su me izagnali, tako da ne mogu imati udjela u baštini Jahvinoj, kao da su mi govorili: 'Idi, služi tuđim bogovima!'"},{"v":20,"t":"Zato neka ne padne moja krv na zemlju daleko od Jahvina lica. Jer kralj je Izraelov izišao u lov na moj život, kao kad tko goni jarebicu po planini.”"},{"v":21,"t":"Tada Šaul reče: “Zgriješio sam! Vrati mi se, sine Davide, neću ti više činiti zla, kad je danas moj život u očima tvojim bio tako drag. Jest, ludo sam radio i teško sam pogriješio!”"},{"v":22,"t":"A David odgovori: “Evo kraljeva koplja, neka dođe jedan od momaka i neka ga uzme!"},{"v":23,"t":"A Jahve će vratiti svakome po njegovoj pravdi i po njegovoj vjernosti: danas te Jahve bijaše predao u moje ruke, ali nisam htio dići ruke svoje na pomazanika Jahvina."},{"v":24,"t":"I gle, kako je danas tvoj život bio drag u mojim očima, tako neka moj život bude drag u Jahvinim očima! I neka me Jahve izbavi iz svake nevolje!”"},{"v":25,"t":"A Šaul doviknu Davidu: “Budi mi blagoslovljen, sine Davide! Zacijelo ćeš izvršiti svoje djelo i uspjet ćeš!” Potom David ode svojim putem, a Šaul se vrati svojoj kući."}]},"27":{"hr":[{"v":1,"t":"David reče u sebi: “Ipak ću jednoga dana poginuti od Šaulove ruke. Zato nema ništa bolje za me nego da se spasim u zemlju Filistejaca. Tada će Šaul odustati da me dalje traži po svim krajevima Izraelovim i izbavit ću se iz njegove ruke.”"},{"v":2,"t":"David se dakle podiže i prijeđe, sa šest stotina ljudi koje je imao, k Akišu, sinu Maokovu, kralju Gata."},{"v":3,"t":"David se nastani kod Akiša u Gatu, on i njegovi ljudi, svaki sa svojom obitelji, a David sa svoje dvije žene, Ahinoamom Jizreelkom i Abigajilom, Nabalovom ženom iz Karmela."},{"v":4,"t":"Kad je Šaul doznao da je David pobjegao u Gat, nije ga više progonio."},{"v":5,"t":"David reče Akišu: “Ako sam našao milost u tvojim očima, neka mi dadu mjesto u jednom gradu u zemlji da se nastanim u njemu. Zašto da tvoj sluga stanuje kod tebe u kraljevskom gradu?”"},{"v":6,"t":"Akiš mu još istoga dana dade Siklag. Stoga Siklag pripada do današnjega dana kraljevima Jude."},{"v":7,"t":"I osta David u filistejskoj zemlji godinu dana i četiri mjeseca."},{"v":8,"t":"David je sa svojim ljudima izlazio da pljačka Gešurce, Girzijce i Amalečane, jer su to bili stanovnici zemlje od Telama preko Šura sve do egipatske zemlje."},{"v":9,"t":"David je pustošio zemlju ne ostavljajući na životu ni čovjeka ni žene, otimao je ovce i goveda, magarce, deve i haljine i vraćao se da sve to donese Akišu."},{"v":10,"t":"Akiš bi ga pitao: “Gdje ste danas pljačkali?” A David bi odgovorio da su pljačkali u Negebu Judinu ili u Negebu Jerahmeelskom ili u Negebu Kenijskom."},{"v":11,"t":"David nije ostavljao na životu ni čovjeka ni žene da ih dovede u Gat jer mišljaše: “Mogli bi nas optužiti i reći: 'Tako je David radio.'” Takav je imao običaj za sve vrijeme dok je boravio u filistejskoj zemlji."},{"v":12,"t":"Akiš je vjerovao Davidu i govorio u sebi: “Baš se omrazio svome narodu, Izraelu! Zato će mi biti sluga dovijeka!”"}]},"28":{"hr":[{"v":1,"t":"U ono vrijeme Filistejci skupiše svoje čete za rat protiv Izraela. I Akiš reče Davidu: “Znaj da ćeš ići sa mnom na vojsku, ti i tvoji ljudi!”"},{"v":2,"t":"A David odgovori Akišu: “Dobro! Sad ćeš vidjeti što će učiniti tvoj sluga!” A Akiš odvrati Davidu: “Dobro! Zato ću te postaviti da budeš mojim čuvarom zauvijek.”"},{"v":3,"t":"Samuel bijaše umro, a sav ga Izrael bijaše oplakao naričući za njim. Ukopali su ga u njegovu gradu Rami. A Šaul bijaše istjerao iz zemlje sve zazivače duhova i vračeve."},{"v":4,"t":"Dok su se Filistejci skupljali te došli i utaborili se kod Šunema, Šaul skupi sve Izraelce te se utabori na Gilboi."},{"v":5,"t":"Kad Šaul ugleda filistejski tabor, uplaši se i srce mu snažno zadrhta."},{"v":6,"t":"Šaul upita za savjet Jahvu, ali mu Jahve ne dade odgovora - ni u snima, ni po Urimu, ni preko proroka."},{"v":7,"t":"Zato Šaul reče svojim slugama: “Potražite mi ženu koja zaziva duhove da odem k njoj i upitam je.” A sluge mu odgovoriše: “Evo, u En Doru ima žena koja zaziva duhove.”"},{"v":8,"t":"Tada se Šaul preruši, obuče druge haljine i otputi se sa dva čovjeka. I dođe noću k onoj ženi i reče joj: “Daj mi vračaj pomoću duha i dozovi mi onoga koga ti reknem.”"},{"v":9,"t":"A žena mu odgovori: “Ta ti znaš što je učinio Šaul i kako je istrijebio iz zemlje zazivače duhova i vračeve. Zašto postavljaš zamke mome životu da me pogubiš?”"},{"v":10,"t":"A Šaul joj se zakle Jahvom govoreći: “Tako mi živog Jahve, nećeš biti ništa kriva za ovo!”"},{"v":11,"t":"Tada žena zapita: “Koga da ti dozovem?” A on odgovori: “Dozovi mi Samuela!”"},{"v":12,"t":"Kad žena ugleda Samuela, povika iza glasa, a onda reče Šaulu: “Zašto si me prevario? Ta ti si Šaul!”"},{"v":13,"t":"A kralj joj odvrati: “Ne boj se! Nego što vidiš?” A žena odgovori Šaulu: “Vidim nešto božansko što se diže iz zemlje.”"},{"v":14,"t":"Šaul je upita: “Kakva je obličja?” A ona odgovori: “Izlazi starac, ogrnut plaštem.” Tada Šaul spozna da je to Samuel, pa pade licem do zemlje i pokloni se."},{"v":15,"t":"Samuel upita Šaula: “Zašto si pomutio moj mir dozivajući me gore?” A Šaul odgovori: “U velikoj sam nevolji jer su Filistejci zavojštili na me, a Bog se okrenuo od mene i ne odgovara mi više ni preko proroka ni u snima. Zato sam dozvao tebe da me poučiš što da činim.”"},{"v":16,"t":"A Samuel odvrati: “Zašto mene pitaš kad se Jahve odvratio od tebe i postao ti neprijateljem?"},{"v":17,"t":"Jahve ti je učinio kako ti je kazao preko mene: istrgao je kraljevstvo iz tvoje ruke i dao ga tvome suparniku, Davidu,"},{"v":18,"t":"jer nisi poslušao riječi Jahvinih i jer nisi izvršio njegova žestokog gnjeva na Amaleku: stoga ti je Jahve danas ovako učinio."},{"v":19,"t":"Jahve će predati, zajedno s tobom, i Izraela u filistejske ruke. Sutra ćeš sa svojim sinovima biti sa mnom, a i tabor izraelski Jahve će predati u filistejske ruke.”"},{"v":20,"t":"Šaul se užasnu i pade na zemlju kako je dug. Spopade ga silan strah od Samuelovih riječi. I ponestade mu snage, jer nije ništa jeo cijeli dan i cijelu noć."},{"v":21,"t":"Kad ona žena dođe k Šaulu i opazi kako je sav zaplašen, reče mu: “Gle, tvoja je službenica poslušala tvoju riječ, stavila sam svoj život na kocku i poslušala tvoje zapovijedi koje si mi naložio."},{"v":22,"t":"Zato sada poslušaj i ti riječi službenice svoje: dopusti da ti pružim zalogaj kruha; jedi da ti se vrati snaga te uzmogneš poći svojim putem.”"},{"v":23,"t":"Ali on ne htjede nego reče: “Neću jesti!” Ali kad ga zaokupiše njegove sluge, zajedno sa ženom, posluša ih, ustade sa zemlje i sjede na postelju."},{"v":24,"t":"Žena je imala kod kuće tele u tovu. Brzo ga zakla, zatim uze brašna, umijesi ga i napeče beskvasnoga kruha."},{"v":25,"t":"Potom stavi sve pred Šaula i njegove ljude. Pošto su jeli, ustadoše i još iste noći krenuše natrag."}]},"29":{"hr":[{"v":1,"t":"Filistejci skupiše sve svoje čete u Afeku, a Izraelci se utaboriše kod izvora u Jizreelu."},{"v":2,"t":"Filistejski su knezovi prolazili sa svojim stotinama i tisućama, a David i njegovi ljudi išli su sasvim na kraju s Akišem."},{"v":3,"t":"Filistejski knezovi zapitaše: “Što hoće ti Hebreji ovdje?” A Akiš odgovori filistejskim knezovima: “Pa ovo je David, sluga izraelskoga kralja Šaula! Već je godinu-dvije kod mene, ali nisam našao na njemu ništa sumnjivo od onoga dana kad je prebjegao k meni pa do današnjega dana.”"},{"v":4,"t":"Ali filistejski knezovi planuše na njega i rekoše mu: “Pošalji toga čovjeka natrag, neka se vrati na mjesto koje si mu označio. Neka ne ide s nama u boj, da se ne okrene protiv nas u boju! Čime bi se on opet umilio svome gospodaru ako ne glavama ovih naših ljudi?"},{"v":5,"t":"To je onaj isti David o kome se pjevalo igrajući: 'Pobi Šaul svoje tisuće, David na desetke tisuća!'”"},{"v":6,"t":"Tada Akiš dozva Davida i reče mu: “Živoga mi Jahve, ti si pošten i meni bi drago bilo da me pratiš u pokretima moje vojske, jer nisam našao nikakva zla na tebi od onoga dana kad si došao k meni pa do današnjega dana. Ali nisi drag u očima knezova."},{"v":7,"t":"Zato se sada vrati i otiđi s mirom kući da ne ozlovoljiš filistejske knezove!”"},{"v":8,"t":"David odvrati Akišu: “Ta što sam učinio i što si zamjerio svome sluzi od onoga dana kad sam stupio u tvoju službu pa do današnjega dana da ne mogu ići da se bijem s neprijateljima svoga gospodara kralja?”"},{"v":9,"t":"A Akiš odgovori Davidu: “Ti znaš da si mi drag kao Božji anđeo, ali su filistejski knezovi rekli: 'Neka ne ide s nama u boj!'"},{"v":10,"t":"Zato ustanite rano ujutro, ti i sluge tvoga gospodara koji su došli s tobom, i otiđite na mjesto koje sam vam označio. I nemoj gajiti u svom srcu nikakve mržnje jer si mi mio. Ustat ćete, dakle, u rano jutro, čim svane, i otići ćete!”"},{"v":11,"t":"Tako David sa svojim ljudima ustade rano i krenu odmah ujutro i vrati se u filistejsku zemlju, a Filistejci odoše u Jizreel."}]},"30":{"hr":[{"v":1,"t":"Kad je David sa svojim ljudima treći dan stigao u Siklag, a to Amalečani bijahu navalili na Negeb i na Siklag; opljačkali su Siklag i ognjem ga spalili."},{"v":2,"t":"Zarobili su žene i sve koji su bili ondje, malo i veliko. Nisu ubili nikoga, nego su samo odveli roblje i otišli svojim putem."},{"v":3,"t":"Kad je, dakle, David sa svojim ljudima došao u grad, vidješe da je grad spaljen, a njihove žene, njihovi sinovi i njihove kćeri odvedeni u ropstvo."},{"v":4,"t":"Tada David i ljudi koji bijahu s njim podigoše glas i plakahu dok im nije ponestalo snage za plač."},{"v":5,"t":"I obje Davidove žene bijahu odvedene u ropstvo - Ahinoama Jizreelka i Abigajila, Nabalova žena iz Karmela."},{"v":6,"t":"David se našao u velikoj nevolji jer su ljudi počeli govoriti da će ga kamenovati, budući da su svi bili ogorčeni, svaki zbog svojih sinova i zbog svojih kćeri. Ali se David ohrabri u Jahvi, svome Bogu."},{"v":7,"t":"David reče svećeniku Ebjataru, Ahimelekovu sinu: “Donesi mi ovamo oplećak!” I Ebjatar donese Davidu oplećak."},{"v":8,"t":"Tada David upita Jahvu za savjet govoreći: “Hoću li u potjeru za onim razbojnicima i hoću li ih stići?” A on mu odgovori: “Idi u potjeru jer ćeš ih zacijelo stići i zarobljenike ćeš izbaviti.”"},{"v":9,"t":"I pođe David sa šest stotina ljudi koji bijahu s njim i dođoše do potoka Besora."},{"v":10,"t":"Odavde David sa četiri stotine ljudi nastavi potjeru, a ostadoše dvije stotine ljudi što bijahu tako umorni da nisu mogli prijeći preko potoka Besora."},{"v":11,"t":"U polju naiđoše na nekog Egipćanina. Dovedoše ga k Davidu, dadoše mu kruha da jede i vode da pije."},{"v":12,"t":"Dadoše mu grudu smokava i dva grozda suhoga grožđa. Kad je to pojeo, vratio mu se život, jer tri dana i tri noći ne bijaše ništa jeo i ništa pio."},{"v":13,"t":"Tada ga David upita: “Čiji si ti i odakle si?” A on odgovori: “Ja sam Egipćanin, sluga jednog Amalečanina. Moj me gospodar ostavio jer sam se razbolio prije tri dana."},{"v":14,"t":"Bili smo provalili u Negeb Keretski i Negeb Judejski, i u Negeb Kalebov, a Siklag smo zapalili ognjem.”"},{"v":15,"t":"David ga upita: “Hoćeš li me odvesti k toj razbojničkoj družbi?” A on odgovori: “Zakuni mi se Bogom da me nećeš pogubiti i da me nećeš predati u ruke mome gospodaru, pa ću te odvesti k njima!”"},{"v":16,"t":"On ga, dakle, odvede, i gle, oni se bijahu razasuli po svem onom kraju, jedući, pijući i slaveći slavlje zbog svega velikog plijena što su ga oteli iz zemlje filistejske i iz zemlje Judine."},{"v":17,"t":"I David ih poče biti i tukao ih je od zore do mraka, izvršujući na njima “herem”, kleto uništenje. Nitko od njih nije izmakao, osim četiri stotine momaka, koji zajahaše na deve i pobjegoše."},{"v":18,"t":"Tako je David izbavio sve što su bili oteli Amalečani; i obje svoje žene izbavi David."},{"v":19,"t":"I ništa im nije nestalo, od najmanjih stvari do najvećih, od plijena sve do sinova i kćeri, sve što im bijaše oteto: sve je vratio David."},{"v":20,"t":"Tada uzeše sve ovce i goveda, dotjeraše ih pred njega vičući: “Ovo je plijen Davidov!”"},{"v":21,"t":"Kad je David došao k onim dvjema stotinama ljudi koji bijahu sustali te ne mogahu ići za Davidom i koje on bijaše ostavio kod potoka Besora, iziđoše oni u susret Davidu i četi njegovoj: približivši se Davidu i četi, pozdraviše ih."},{"v":22,"t":"Tada progovoriše svi zlobnici i ništarije između ljudi koji su išli s Davidom i rekoše: “Budući da nisu išli s nama, ne dajmo im ništa od plijena koji smo izbavili, nego samo svakome njegovu ženu i njegovu djecu, neka ih povedu sa sobom i neka idu!”"},{"v":23,"t":"Ali David reče: “Ne činite tako, braćo moja, poslije onoga što nam je dao Jahve: on nas je čuvao i predao nam u ruke razbojničku družbu koja bijaše izišla protiv nas."},{"v":24,"t":"Ta tko će vas poslušati u tome? Jer kakav je dio onome koji ide u boj, takav je dio onome koji ostaje kod tovara. Jednak dio neka imaju svi.”"},{"v":25,"t":"Tako ostade od onoga dana unapredak. David to učini uredbom i zakonom u Izraelu sve do današnjeg dana."},{"v":26,"t":"Kad je David došao u Siklag, posla dio plijena starješinama Jude, po pojedinim njihovim gradovima, s porukom: “Evo za vas dar od plijena Jahvinih neprijatelja!”"},{"v":27,"t":"Onima u Betulu, onima u Rami u Negebu i onima u Jatiru;"},{"v":28,"t":"onima u Aroeru, onima u Sifmotu i onima u Eštemoi;"},{"v":29,"t":"onima u Karmelu, onima u jerahmeelskim gradovima i onima u kenijskim gradovima;"},{"v":30,"t":"onima u Hormi, onima u Bor Ašanu i onima u Eteru;"},{"v":31,"t":"onima u Hebronu i u svim onima mjestima u koja je dolazio David sa svojim ljudima."}]},"31":{"hr":[{"v":1,"t":"Filistejci su zavojštili na Izraelce, a Izraelci su pobjegli pred njima i padali pobijeni po gori Gilboi."},{"v":2,"t":"Filistejci stisnuše Šaula i njegove sinove i pogubiše Šaulove sinove Jonatana, Abinadaba i Malki-Šuu."},{"v":3,"t":"Boj je postao žešći oko Šaula. Iznenadiše ga strijelci s lukovima i on pade teško ranjen od strijelaca."},{"v":4,"t":"Šaul tada reče svome štitonoši: “Izvuci svoj mač i probodi me da ne dođu ti neobrezanici i ne narugaju mi se.” Ali se njegov štitonoša prestravi i ne htjede toga učiniti. Zato Šaul uze mač i baci se na nj."},{"v":5,"t":"Kad je štitonoša vidio da je Šaul umro, baci se i on na svoj mač i umrije s njim."},{"v":6,"t":"Tako onoga dana pogiboše zajedno Šaul, njegova tri sina, njegov štitonoša i svi njegovi ljudi."},{"v":7,"t":"Kad Izraelci koji bijahu na drugoj strani doline i na drugoj strani Jordana vidješe da su sinovi Izraelovi pobjegli i da je poginuo Šaul sa sinovima, ostaviše svoje gradove te se razbježaše. Filistejci dođoše i nastaniše se u njima."},{"v":8,"t":"Kad su sutradan došli Filistejci da oplijene pobijeđene, nađoše Šaula i njegova tri sina gdje leže na gori Gilboi."},{"v":9,"t":"Oni mu odsjekoše glavu i skidoše s njega oružje, koje poslaše po svoj filistejskoj zemlji naokolo, javljajući veselu vijest svojim idolima i narodu."},{"v":10,"t":"Potom oružje metnuše u Aštartin hram, a Šaulovo mrtvo tijelo pribiše na zid grada Bet Šana."},{"v":11,"t":"Ali kad oni u Jabešu Gileadskom čuše što su Filistejci učinili od Šaula,"},{"v":12,"t":"ustadoše svi hrabri ljudi i, pošto su hodili svu noć, uzeše Šaulovo mrtvo tijelo i tjelesa njegovih sinova sa zida grada Bet Šana pa ih donesoše u Jabeš i ondje spališe."},{"v":13,"t":"Potom uzeše njihove kosti i ukopaše ih pod tamarisom u Jabešu i postiše sedam dana."}]}},"2SA":{"1":{"hr":[{"v":1,"t":"Poslije Šaulove smrti David se vratio kući pobijedivši Amalečane. Dva je dana proveo u Siklagu."},{"v":2,"t":"Trećega dana dođe neki čovjek iz Šaulova tabora, razdrtih haljina i prahom posute glave. Došavši k Davidu, baci se na zemlju i pokloni mu se."},{"v":3,"t":"David ga upita: “Odakle dolaziš?” A on mu odgovori: “Umakao sam iz izraelskog tabora.”"},{"v":4,"t":"A David ga upita: “Što se dogodilo? Pripovijedaj mi!” On odvrati: “Narod je pobjegao iz boja, a mnogo je ljudi i poginulo. Mrtvi su i Šaul i njegov sin Jonatan.”"},{"v":5,"t":"Nato David upita mladoga glasonošu: “Kako znaš da je poginuo Šaul i njegov sin Jonatan?”"},{"v":6,"t":"A mladi glasonoša odgovori: “Slučajno sam došao na goru Gilbou i vidio Šaula kako se upro u svoje koplje, a bojna kola i konjanici natisnuli se za njim."},{"v":7,"t":"Šaul, obazrevši se, ugleda mene pa me zovnu, a ja mu se odazvah: 'Evo me!'"},{"v":8,"t":"I upita me on: 'Tko si ti?' A ja mu odgovorih: 'Amalečanin sam.'"},{"v":9,"t":"Tada mi on reče: 'Dođi ovamo k meni pa me ubij, jer me obuzeo smrtni grč, a duša je još sva u meni!'"},{"v":10,"t":"Pristupih k njemu i zadadoh mu smrtni udarac, jer sam znao da neće preživjeti nakon pada. Zatim uzeh kraljevski znak koji mu bijaše na glavi i narukvicu koju imaše na ruci i, evo, donesoh to svome gospodaru.”"},{"v":11,"t":"Tada David zgrabi svoje haljine i razdrije ih, a tako i svi ljudi koji bijahu s njim."},{"v":12,"t":"I naricali su, plakali i postili do večera za Šaulom i za njegovim sinom Jonatanom, za Jahvinim narodom i za domom Izraelovim što izginuše od mača."},{"v":13,"t":"Potom David upita mladoga glasonošu: “Odakle si ti?” A on odgovori: “Ja sam sin jednoga došljaka, Amalečanina.”"},{"v":14,"t":"Tada mu reče David: “Kako se nisi bojao dići ruku da ubiješ pomazanika Jahvina?”"},{"v":15,"t":"I dozva David jednoga od momaka i zapovjedi mu: “Dođi ovamo i smakni ga!” Udari ga momak i on umrije."},{"v":16,"t":"A David mu još doviknu: “Tvoja krv na tvoju glavu! Tvoja su usta posvjedočila protiv tebe kad si rekao: 'Ja sam ubio pomazanika Jahvina.'”"},{"v":17,"t":"Tada David zapjeva ovu tužaljku za Šaulom i za njegovim sinom Jonatanom."},{"v":18,"t":"Zapisana je u Knjizi Pravednikovoj da je uče sinovi Judini. David reče:"},{"v":19,"t":"“Oh, kako ti slava pade, Izraele, izginuše div-junaci na tvom visu!"},{"v":20,"t":"O porazu vi u Gatu ne pričajte, aškelonskim ulicama ne glasite, da se kćeri ne vesele filistejske, mlade žene da ne kliču nevjerničke."},{"v":21,"t":"O Gilbojske gore klete, rosa na vas ne padala nit vas kiša s neba prala! Vaša polja ne vraćala rod za sjeme, jer kod vas je osramoćen štit junaka! Štit Šaulov nije bio uljem mazan,"},{"v":22,"t":"nego krvlju ranjenika, mašću palih! Luk Jonate nikad nije promašio, mač Šaulov nikad bezuspješan bio!"},{"v":23,"t":"Šaul i Jonata, ljupki, ponositi, ni živi se ne rastaše, ni u smrti! Od orlova bjehu brži, od lavova snagom jači!"},{"v":24,"t":"Za Šaulom sad plačite, Izraelke, jer je u kras i u grimiz vas odijevo! Uz to zlatan nakit on je na ruho vam pričvršćivo."},{"v":25,"t":"Usred boja poginuše div-junaci! Smrt me tvoja, Jonatane, ožalosti!"},{"v":26,"t":"Žao mi je tebe, brate, Jonatane! Kako li mi drag bijaše ti veoma! Ljubav tvoja bješe meni još od ženske čudesnija."},{"v":27,"t":"Oh, kako su izginuli div-junaci, i oružje bojno kako skršeno je!”"}]},"2":{"hr":[{"v":1,"t":"Poslije toga David upita Jahvu ovako: “Treba li da pođem u koji Judin grad?” A Jahve mu odgovori: “Pođi!” David opet upita: “Kamo da pođem?” A odgovor bješe: “U Hebron!”"},{"v":2,"t":"Tako David ode onamo, a s njim i njegove dvije žene, Ahinoama iz Jizreela i Abigajila, Nabalova žena iz Karmela."},{"v":3,"t":"I ljudi koji bijahu s Davidom odoše s njim, svaki sa svojom obitelji, i nastaniše se u gradićima Hebrona."},{"v":4,"t":"Tada dođoše ljudi iz Jude i pomazaše ondje Davida za kralja nad domom Judinim. Tada javiše Davidu da su ljudi iz Jabeša u Gileadu pokopali Šaula."},{"v":5,"t":"Nato David posla glasnike k Jabešanima u Gileadu i poruči im: “Budite blagoslovljeni od Jahve što ste izvršili to djelo ljubavi prema svome gospodaru Šaulu i što ste ga pokopali!"},{"v":6,"t":"Zato neka vam Jahve iskaže svoju ljubav i dobrotu, a i ja ću vam učiniti dobro zato što ste tako radili."},{"v":7,"t":"A sada se ohrabrite i budite junaci, jer je Šaul, vaš gospodar, poginuo, a mene je Judin dom pomazao za svoga kralja.”"},{"v":8,"t":"Ali Abner, sin Nerov, vojvoda Šaulove vojske, bijaše uzeo Šaulova sina Išbaala i doveo ga prijeko u Mahanajim."},{"v":9,"t":"Ondje ga je postavio za kralja nad Gileadom, nad Ašeranima, nad Jizreelom, Efrajimom, Benjaminom i nad svim Izraelom."},{"v":10,"t":"Išbaalu, sinu Šaulovu, bijaše četrdeset godina kad je postao kraljem nad Izraelom, a kraljevao je dvije godine. Samo je Judin dom pristao uz Davida."},{"v":11,"t":"A David je kraljevao u Hebronu nad Judinim domom sedam godina i šest mjeseci."},{"v":12,"t":"Potom iziđe Abner, Nerov sin, s ljudima Šaulova sina Išbaala iz Mahanajima prema Gibeonu."},{"v":13,"t":"Ali i Joab, Sarvijin sin, iziđe s Davidovim ljudima iz Hebrona i srete se s njima kod Gibeonskog jezera. Tu se zaustaviše, ovi s jedne strane jezera, a oni s druge strane."},{"v":14,"t":"Tada Abner reče Joabu: “Neka ustanu mladići i neka se bore pred nama!” A Joab odgovori: “Neka ustanu!”"},{"v":15,"t":"I ustadoše, pa ih izbrojiše: dvanaest od Benjamina za Išbaala, Šaulova sina, i dvanaest od Davidovih ljudi."},{"v":16,"t":"I svaki dohvati svoga protivnika za glavu i zabode mu mač u bok, tako da su svi popadali zajedno. Zato se to mjesto prozvalo Polje bokova, a leži kod Gibeona."},{"v":17,"t":"Potom se zametnu onoga dana vrlo žestoka bitka i Davidove čete razbiše Abnera i Izraelce."},{"v":18,"t":"A bijahu ondje tri Sarvijina sina: Joab, Abišaj i Asahel; a Asahel bijaše brz u trku kao gazela u polju."},{"v":19,"t":"I jurnu Asahel u potjeru za Abnerom; u stopu je slijedio Abnera ne skrećući ni desno ni lijevo."},{"v":20,"t":"Abner se obazre i upita: “Jesi li to ti, Asahele?” A on odgovori: “Jesam.”"},{"v":21,"t":"A Abner mu reče: “Okreni se nadesno ili nalijevo pa zgrabi jednoga od tih mladića i uzmi njegovu odoru!” Ali Asahel nije htio da skrene od njega."},{"v":22,"t":"Abner opet reče Asahelu: “Ukloni se od mene! Zašto da te sastavim sa zemljom? Kako bih onda još smio doći na oči tvome bratu Joabu?”"},{"v":23,"t":"Ali on nikako nije htio da se ukloni. Zato ga Abner udari stražnjim krajem koplja u trbuh tako da mu je koplje izašlo kroz leđa van: on ondje pade i umrije na mjestu. I ustavljao se tko god je došao na ono mjesto gdje je pao i umro Asahel."},{"v":24,"t":"Ali Joab i Abišaj nastaviše da gone Abnera, a kad je sunce zašlo, stigoše do brežuljka Ame, koji leži istočno od doline, na putu prema Gebi."},{"v":25,"t":"Dotle se Benjaminovi sinovi skupiše za Abnerom, sastaviše četu i stadoše na vrh brežuljka Ame."},{"v":26,"t":"Tada Abner viknu Joabu: “Zar će nas dovijeka proždirati mač? Ne znaš li da će to svršiti nesrećom? Kad ćeš napokon kazati svojim ljudima da se okane gonjenja svoje braće?”"},{"v":27,"t":"A Joab odvrati: “Tako mi živog Jahve, da ti nisi progovorio, tek bi se sutra ujutro ovi ljudi okanili gonjenja svoje braće.”"},{"v":28,"t":"Nato Joab zatrubi u rog i sva vojska stade: prestadoše goniti Izraela i ne nastaviše boja."},{"v":29,"t":"Abner i njegovi ljudi išli su kroz Arabu cijelu onu noć; onda prijeđoše preko Jordana, nastaviše put cijelo jutro i stigoše napokon u Mahanajim."},{"v":30,"t":"Kad je Joab odustao od potjere za Abnerom i skupio svu vojsku, vidješe da između Davidovih ljudi nema devetnaestorice, i uz to Asahela."},{"v":31,"t":"A Davidovi su ljudi od Benjaminovih sinova, Abnerovih vojnika, pobili tri stotine i šezdeset ljudi."},{"v":32,"t":"Asahela ponesoše i pokopaše u grobu njegova oca u Betlehemu. A Joab i njegovi ljudi išli su svu noć i već se bijaše zadanilo kad stigoše u Hebron."}]},"3":{"hr":[{"v":1,"t":"Rat između Šaulove kuće i Davidove kuće potrajao je još dugo vremena, ali je David sve više jačao, a Šaulova kuća postajala sve slabija."},{"v":2,"t":"Davidu se rodiše sinovi u Hebronu. Prvenac mu je bio Amnon, od Ahinoame Jizreelke;"},{"v":3,"t":"drugi mu je bio Kileab, od Abigajile, žene Nabalove iz Karmela; treći Abšalom, sin Maake, kćeri gešurskoga kralja Tolmaja;"},{"v":4,"t":"četvrti Adonija, sin Hagitin; peti Šefatja, sim Abitalin;"},{"v":5,"t":"šesti Jitream, od Egle, Davidove žene. Ti se Davidu rodiše u Hebronu."},{"v":6,"t":"Dok je trajao rat između Šaulove kuće i Davidove kuće, Abner je malo-pomalo prisvajao svu vlast u Šaulovoj kući."},{"v":7,"t":"A u kući bijaše Šaulova inoča po imenu Rispa, kći Ajina: nju Abner uze sebi. A Išbaal upita Abnera: “Zašto si se približio inoči moga oca?”"},{"v":8,"t":"Na te Išbaalove riječi Abner se razgnjevi i reče: “Zar sam ja pasja glava u Judi? Do danas sam samo dobro činio domu tvoga oca Šaula, njegovoj braći i njegovim prijateljima; nisam dopustio da padneš u Davidove ruke, a ti me danas prekoravaš zbog obične žene!"},{"v":9,"t":"Neka Abneru Bog učini ovo zlo i neka mu doda drugo ako ne izvršim kako se Jahve zakleo Davidu:"},{"v":10,"t":"da će oduzeti kraljevstvo Šaulovoj kući i da će utvrditi Davidov prijesto nad Izraelom i nad Judom od Dana pa do Beer Šebe!”"},{"v":11,"t":"Išbaal se ne usudi odgovoriti ni riječi Abneru jer ga se bojaše."},{"v":12,"t":"Nato Abner posla glasnike k Davidu i poruči mu: “Čija je zemlja?” Htio je reći: “Učini savez sa mnom i moja će ti ruka pomoći da okupiš oko sebe svega Izraela.”"},{"v":13,"t":"David odgovori Abneru: “Dobro! Učinit ću savez s tobom! Ali samo jedno tražim od tebe: ne smiješ mi doći na oči ako ne dovedeš sa sobom Mikalu, Šaulovu kćer, kad dođeš da vidiš moje lice.”"},{"v":14,"t":"Ujedno posla David glasnike i k Išbaalu, Šaulovu sinu, s porukom: “Vrati mi moju ženu Mikalu, koju sam stekao stotinom filistejskih obrezaka.”"},{"v":15,"t":"Išbaal posla po nju i uze je od njezina muža Paltiela, Lajiševa sina."},{"v":16,"t":"A njezin muž pođe s njom i pratio ju je plačući sve do Bahurima. Tada mu Abner reče: “Hajde, vrati se sada kući!” I on se vrati."},{"v":17,"t":"Abner je već bio razgovarao s Izraelovim starješinama i rekao im: “Već odavna želite Davida za svoga kralja."},{"v":18,"t":"Učinite to sada, jer je Jahve rekao o Davidu ovo: 'Rukom svoga sluge Davida izbavit ću svoj narod Izraela iz ruke filistejske i iz ruku svih njegovih neprijatelja.'”"},{"v":19,"t":"Tako je Abner govorio i Benjaminovim sinovima, a onda je otišao u Hebron da javi Davidu sve što se svidjelo Izraelu i domu Benjaminovu."},{"v":20,"t":"Kad je Abner došao k Davidu u Hebron, i s njim dvadeset ljudi, David priredi gozbu Abneru i ljudima koji bijahu s njim."},{"v":21,"t":"Tada Abner reče Davidu: “Hajdemo! Ja ću skupiti svega Izraela oko gospodara moga kralja: oni će sklopiti s tobom savez i ti ćeš kraljevati nad svim što budeš želio.” David otpusti Abnera, koji ode u miru."},{"v":22,"t":"I gle, Davidovi se ljudi s Joabom upravo vraćali sa četovanja, noseći sa sobom bogat plijen, a Abner nije više bio kod Davida u Hebronu, jer ga David bijaše otpustio te je on otišao u miru."},{"v":23,"t":"Kad stiže Joab i sva vojska što je išla s njim, javiše Joabu da je Abner, Nerov sin, bio došao kralju i da ga je kralj otpustio da ode u miru."},{"v":24,"t":"Tada Joab dođe kralju i reče mu: “Što si učinio? Abner je došao k tebi, zašto si ga otpustio da ode u miru?"},{"v":25,"t":"Zar ne znaš Abnera, Nerova sina? Došao je da te prevari, da dozna tvoje korake, da dozna sve što činiš!”"},{"v":26,"t":"Potom izađe Joab od Davida i posla glasnike za Abnerom, koji ga vratiše, od studenca Sire, a David nije znao ništa o tome."},{"v":27,"t":"Kad se Abner vratio u Hebron, odvede ga Joab u stranu iza vrata, kao da želi s njim nesmetano govoriti, i ondje ga smrtno rani u slabine da se osveti za krv svoga brata Asahela."},{"v":28,"t":"Kad je David to poslije čuo, reče: “Ja i moje kraljevstvo nevini smo pred Jahvom dovijeka za krv Abnera, sina Nerova."},{"v":29,"t":"Neka padne na Joabovu glavu i na sav njegov očinski dom! Nikad ne ponestalo u Joabovu domu ljudi bolesnih od gnojenja ili od gube, ljudi koji se laćaju vretena ili padaju od mača, ljudi koji nemaju kruha!” -"},{"v":30,"t":"Joab i njegov brat Abišaj ubili su Abnera jer je on pogubio njihova brata Asahela u boju kod Gibeona. -"},{"v":31,"t":"Nato David reče Joabu i svoj vojsci koja je bila s njim: “Razderite svoje haljine, obucite kostrijet i naričite za Abnerom!” I kralj David pođe za nosilima."},{"v":32,"t":"Kad su ukopali Abnera u Hebronu, udari kralj u glasan plač na grobu Abnerovu, a plakao je i sav narod."},{"v":33,"t":"Tada kralj ispjeva ovu tužaljku za Abnerom: “Zar morade umrijeti Abner kako umire luda?"},{"v":34,"t":"Ruke tvoje ne bijahu vezane, noge tvoje ne bijahu okovane. Pao si kao što se pada od zlikovaca!” Tada sav narod još ljuće zaplaka za njim."},{"v":35,"t":"Nato pristupi sav narod nutkajući Davida da jede dok je još dana, ali se David zakle ovako: “Neka mi Bog učini ovo zlo i neka mi doda drugo zlo ako okusim kruha ili što drugo prije zalaska sunca!”"},{"v":36,"t":"Sav je narod to čuo, i bilo mu je po volji, kao što je narod i sve drugo odobravao što god je kralj činio."},{"v":37,"t":"Toga dana sav narod i sav Izrael spozna da kralj nije kriv u umorstvu Abnera, sina Nerova."},{"v":38,"t":"Nato kralj reče svojim dvoranima: “Ne znate li da je danas pao knez i velik čovjek u Izraelu?"},{"v":39,"t":"Ali ja sam sada još slab, iako sam pomazani kralj, a ovi ljudi, Sarvijini sinovi, jači su od mene. Neka Jahve plati zločincu po njegovoj zloći!”"}]},"4":{"hr":[{"v":1,"t":"Kad je Šaulov sin Išbaal čuo da je poginuo Abner u Hebronu, klonuše mu ruke i sav se Izrael zaprepasti."},{"v":2,"t":"A Šaulov sin Išbaal imaše dvojicu vođa svojih četa; jedan se zvao Baana, a drugi Rekab; bili su sinovi Rimona Beeroćanina iz Benjaminova plemena, jer se Beerot pribraja k Benjaminu."},{"v":3,"t":"A Beeroćani bijahu pobjegli u Gitajim, gdje su ostali kao došljaci do današnjeg dana."},{"v":4,"t":"Šaulov sin Jonatan imao je sina hroma na obje noge. Njemu je bilo pet godina kad je iz Jizreela došao glas o Šaulovoj i Jonatanovoj pogibiji. Njegova ga dadilja uze i pobježe, ali u brzini bijega dijete pade i osta hromo. Ime mu bijaše Meribaal."},{"v":5,"t":"Sinovi Rimona Beeroćanina, Rekab i Baana, digoše se i dođoše za najveće dnevne vrućine Išbaalu do kuće, a on upravo spavaše podnevni počinak."},{"v":6,"t":"A vratarica, čisteći pšenicu, bijaše zadrijemala te je spavala. Rekab i njegov brat Baana prošuljaše se kraj nje."},{"v":7,"t":"Kad su ušli u kuću, on je ležao na postelji u svojoj spavaonici. Oni ga ubiše, odsjekoše mu glavu i uzeše je i cijelu su onu noć išli putem kroz Arabu."},{"v":8,"t":"Glavu Išbaalovu donesoše Davidu u Hebron i rekoše kralju: “Evo glave Išbaala, sina Šaulova, tvoga neprijatelja koji ti je radio o glavi. Jahve je danas krvavo osvetio moga gospodara i kralja na Šaulu i njegovu rodu.”"},{"v":9,"t":"Ali David odvrati Rekabu i njegovu bratu Baani, sinovima Rimona iz Beerota, i reče im: “Tako mi živog Jahve koje me izbavio iz svake nevolje!"},{"v":10,"t":"Onaj koji mi je javio da je poginuo Šaul mislio je da mi javlja radosnu vijest, a ja sam ga uhvatio i pogubio u Siklagu da mu platim za njegovu dobru vijest!"},{"v":11,"t":"Što ću tek učiniti sa zlikovcima koji su ubili poštena čovjeka u njegovoj kući, na njegovoj postelji! Zar da ne tražim od vas račun za njegovu krv i da vas ne istrijebim sa zemlje?”"},{"v":12,"t":"Nato David zapovjedi vojnicima te ih pogubiše. Potom im odsjekoše ruke i noge i objesiše ih kod jezera u Hebronu. Išbaalovu glavu uzeše i pokopaše u Abnerovu grobu u Hebronu."}]},"5":{"hr":[{"v":1,"t":"Tada se sabraše sva izraelska plemena k Davidu u Hebron i rekoše: “Evo, mi smo od tvoje kosti i od tvoga mesa."},{"v":2,"t":"Još prije, dok je još Šaul bio kralj nad nama, ti si upravljao svim pokretima Izraela, a Jahve ti je rekao: 'Ti ćeš pasti moj izraelski narod i ti ćeš biti knez nad Izraelom!'”"},{"v":3,"t":"Tako dođoše sve izraelske starješine kralju u Hebron, a kralj David sklopi s njima savez u Hebronu pred Jahvom; i pomazaše Davida za kralja nad Izraelom."},{"v":4,"t":"Trideset je godina bilo Davidu kad je postao kralj, a kraljevao je četrdeset godina."},{"v":5,"t":"U Hebronu je kraljevao nad Judom sedam godina i šest mjeseci, a u Jeruzalemu kraljevaše trideset i tri godine nad svim Izraelom i nad Judom."},{"v":6,"t":"David krene s ljudima na Jeruzalem protiv Jebusejaca, koji su živjeli u onoj zemlji. Ali oni poručiše Davidu: “Nećeš ući ovamo! Slijepci će te i kljasti odbiti!” (To je imalo značiti: David neće ući ovamo.)"},{"v":7,"t":"Ipak David osvoji Sionsku tvrđavu, to jest Davidov grad."},{"v":8,"t":"Onoga dana reče David: “Tko god pobije Jebusejce i popne se kroz prorov ...” A kljaste i slijepe mrzi David iz sve duše. (Stoga se kaže: Slijepci i kljasti neka ne ulaze u Hram.)"},{"v":9,"t":"David se nastani u tvrđavi i prozva je Davidov grad. Tada David podiže zid unaokolo od Mila pa unutra."},{"v":10,"t":"David je postajao sve silniji, jer Jahve, Bog nad vojskama, bijaše s njim."},{"v":11,"t":"Tirski kralj Hiram posla k Davidu izaslanstvo i cedrova drveta, tesara i zidara, koji sagradiše dvor Davidu."},{"v":12,"t":"Tada David spozna da ga je Jahve potvrdio za kralja nad Izraelom i da je vrlo uzvisio njegovo kraljevstvo radi svojega izraelskog naroda."},{"v":13,"t":"Po dolasku iz Hebrona David uze još inoča i žena iz Jeruzalema; i rodi se Davidu još sinova i kćeri."},{"v":14,"t":"Evo imena djece koja mu se rodiše u Jeruzalemu: Šamua, Šobab, Natan, Salomon,"},{"v":15,"t":"Jibhar, Elišua, Nefeg, Jafija,"},{"v":16,"t":"Elišama, Beeljada i Elifelet."},{"v":17,"t":"Kad su Filistejci čuli da su Davida pomazali za kralja nad Izraelom, iziđoše svi da se dočepaju Davida. Čuvši to, David siđe u svoj zaklon."},{"v":18,"t":"Filistejci dođoše i raširiše se po Refaimskoj dolini."},{"v":19,"t":"Tada David upita Jahvu: “Mogu li napasti Filistejce? Hoćeš li ih predati meni u ruke?” Jahve odgovori Davidu: “Napadni! Predat ću Filistejce tebi u ruke!”"},{"v":20,"t":"Tada David dođe u Baal Perasim i ondje ih pobi. David reče: “Jahve je preda mnom prodro među moje neprijatelje kao što voda prodire.” Stoga se ono mjesto prozvalo Baal Perasim."},{"v":21,"t":"Ostavili su ondje svoje bogove; a David i njegovi ljudi odnesoše ih."},{"v":22,"t":"Filistejci opet dođoše i raširiše se po Refaimskoj dolini."},{"v":23,"t":"David opet upita Jahvu, a on mu odgovori: “Ne idi pred njih, nego im zađi za leđa i navali na njih s protivne strane Bekaima."},{"v":24,"t":"Kad začuješ topot koraka po bekaimskim vrhovima, onda se požuri, jer će tada Jahve ići pred tobom da pobije filistejsku vojsku.”"},{"v":25,"t":"David učini kako mu je zapovjedio Jahve i pobi Filistejce od Gibeona sve do ulaza u Gezer."}]},"6":{"hr":[{"v":1,"t":"Jednoga dana David opet skupi svu izabranu momčad u Izraelu, trideset tisuća ljudi."},{"v":2,"t":"Zatim David i sva vojska što je bila s njim krenu na put i odoše u Baalu Judinu da odande donesu Kovčeg Božji, što nosi ime Jahve Sebaota koji stoluje nad kerubinima."},{"v":3,"t":"Kovčeg Božji metnuše na nova kola, iznijevši ga iz kuće Abinadabove, koja je stajala na brežuljku. Uza i Ahjo, Abinadabovi sinovi, pratili su kola."},{"v":4,"t":"Uza je stupao kraj Kovčega Božjeg, a Ahjo išao pred njim."},{"v":5,"t":"David i sav dom Izraelov igrahu pred Jahvom iz sve snage pjevajući uza zvuke citara, harfa, bubnjeva, udaraljki i cimbala."},{"v":6,"t":"Kad su došli do Nakonova gumna, posegnu Uza rukom za Kovčegom Božjim da ga pridrži jer ga volovi umalo ne prevrnuše."},{"v":7,"t":"Ali se Jahve razgnjevio na Uzu: Bog ga na mjestu udari za taj prijestup, tako da je umro ondje, kraj Kovčega Božjega."},{"v":8,"t":"Davidu bijaše žao što je Jahve onako udario Uzu, i on prozva ono mjesto Peres Uza, kako se zove i dan-danas."},{"v":9,"t":"Toga se dana David uplaši Jahve i reče u sebi: “Kako bi mogao doći k meni Kovčeg Jahvin?”"},{"v":10,"t":"Zato David ne htjede dovesti Kovčeg Jahvin k sebi, u Davidov grad, nego ga otpremi u kuću Obed-Edoma iz Gata."},{"v":11,"t":"I ostade Jahvin Kovčeg u kući Obed-Edomovoj u Gatu tri mjeseca i Jahve blagoslovi Obed-Edoma i svu njegovu obitelj."},{"v":12,"t":"Kad su kralju javili da je Jahve blagoslovio Obed-Edomovu obitelj i sav njegov posjed zbog Kovčega Božjeg, ode David i ponese Kovčeg Božji iz Obed-Edomove kuće gore u Davidov grad s velikim veseljem."},{"v":13,"t":"Tek što su nosioci Kovčega Božjeg pokročili šest koraka, David žrtvova vola i tovna ovna."},{"v":14,"t":"David je igrao iz sve snage pred Jahvom, a bio je ogrnut samo lanenim oplećkom."},{"v":15,"t":"Tako su David i sav Izraelov dom nosili gore Kovčeg Jahvin kličući i trubeći u rog."},{"v":16,"t":"A kad je Kovčeg Jahvin ulazio u Davidov grad, Šaulova je kći Mikala gledala kroz prozor i vidjela kralja Davida kako skače i vrti se pred Jahvom i prezre ga ona u svome srcu."},{"v":17,"t":"Tada unesoše Kovčeg Jahvin i postaviše ga usred šatora koji mu bijaše razapeo David. Onda David prinese pred Jahvom paljenice i pričesnice."},{"v":18,"t":"Pošto je prinio paljenice i pričesnice, David blagoslovi narod imenom Jahve Sebaota."},{"v":19,"t":"Potom razdijeli među sav narod, među sve mnoštvo Izraelovo, ljudima i ženama, svakome po jedan kruh, komad mesa i kolač od suhoga grožđa. Zatim se raziđe sav narod, svaki svojoj kući."},{"v":20,"t":"Kad se David vratio kući da blagoslovi svoju obitelj, Šaulova kći Mikala iziđe u susret Davidu i reče mu: “Kako se časno danas ponio Izraelov kralj kad se otkrio pred očima sluškinja slugu svojih kao što se otkriva prost čovjek!”"},{"v":21,"t":"Ali David odgovori Mikali: “Pred Jahvom ja igram! Tako mi živoga Jahve, koji me izabrao mjesto tvog oca i mjesto svega njegova doma da me postavi za kneza nad Izraelom, narodom Jahvinim: pred Jahvom ću igrati!"},{"v":22,"t":"I još ću se dublje poniziti. Bit ću neznatan u tvojim očima, ali pred sluškinjama o kojima govoriš, pred njima ću biti u časti.”"},{"v":23,"t":"A Mikala, Šaulova kći, ne imade poroda do dana svoje smrti."}]},"7":{"hr":[{"v":1,"t":"Kad se David nastanio u svojem dvoru i kad mu je Jahve pribavio mir od svih njegovih neprijatelja unaokolo,"},{"v":2,"t":"reče kralj proroku Natanu: “Pogledaj! Ja, evo, stojim u dvoru od cedrovine, a Kovčeg Božji stoji pod šatorom.”"},{"v":3,"t":"A Natan odgovori kralju: “Idi i čini sve što ti je na srcu jer je Jahve s tobom.”"},{"v":4,"t":"Ali još iste noći dođe Natanu ova Jahvina riječ:"},{"v":5,"t":"“Idi i reci mome sluzi Davidu: Ovako govori Jahve: 'Zar ćeš mi ti sagraditi kuću da u njoj prebivam?"},{"v":6,"t":"Nisam nikad prebivao u kući otkako sam izveo iz Egipta sinove Izraelove pa do današnjega dana, nego sam bio lutalac pod šatorom i u prebivalištu."},{"v":7,"t":"Dok sam hodio sa svim Izraelovim sinovima, jesam li ijednu riječ rekao nekomu od Izraelovih sudaca kojima sam zapovjedio da budu pastiri mojem narodu izraelskom i kazao: 'Zašto mi ne sagradite kuću od cedrovine?'"},{"v":8,"t":"Zato sad ovo reci mome sluzi Davidu: Ovako govori Jahve nad vojskama: Ja sam te doveo s pašnjaka, od ovaca i koza, da budeš knez nad mojim izraelskim narodom."},{"v":9,"t":"Bio sam s tobom kuda si god išao, iskorijenio sam sve tvoje neprijatelje pred tobom. Ja ću ti pribaviti veliko ime, kao što je velikaško ime na zemlji."},{"v":10,"t":"Odredit ću prebivalište svojem izraelskom narodu, posadit ću ga da živi na svojem mjestu i da ne luta više naokolo, niti da ga zlikovci muče kao prije,"},{"v":11,"t":"onda kad sam odredio suce nad svojim izraelskim narodom. Ja ću mu pribaviti mir od svih njegovih neprijatelja. Jahve će te učiniti velikim. Jahve će ti podići dom."},{"v":12,"t":"I kad se ispune tvoji dani i ti počineš kod svojih otaca, podići ću tvoga potomka nakon tebe, koji će se roditi od tvoga tijela, i utvrdit ću njegovo kraljevstvo."},{"v":13,"t":"On će sagraditi dom imenu mojem, a ja ću utvrditi njegovo prijestolje zauvijek."},{"v":14,"t":"Ja ću njemu biti otac, a on će meni biti sin: ako učini što zlo, kaznit ću ga ljudskom šibom i udarcima kako ih zadaju sinovi ljudski."},{"v":15,"t":"Ali svoje naklonosti neću odvratiti od njega, kao što sam je odvratio od Šaula koga sam uklonio ispred tebe."},{"v":16,"t":"Tvoja će kuća i tvoje kraljevstvo trajati dovijeka preda mnom, tvoje će prijestolje čvrsto stajati zasvagda.'”"},{"v":17,"t":"Natan prenese Davidu sve te riječi i cijelo viđenje."},{"v":18,"t":"Nato kralj David uđe u šator i stade pred Jahvom i pomoli se: “Tko sam ja, Gospode Jahve, i što je moj dom te si me doveo dovde?"},{"v":19,"t":"Pa i to je još premalo u tvojim očima, Gospode Jahve, te daješ svoja obećanja kući svoga sluge za daleku budućnost i gledaš na me kao na ugledna čovjeka!"},{"v":20,"t":"Ali što bi ti David još mogao kazati, kad ti sam poznaješ svoga slugu, Gospode Jahve!"},{"v":21,"t":"Radi svoje riječi i po svome srcu učinio si sve ovo veliko djelo, obznanivši ove veličajnosti."},{"v":22,"t":"Zato si velik, Gospode Jahve; nema takvoga kakav si ti i nema Boga osim tebe, po svemu što smo ušima svojim čuli."},{"v":23,"t":"Postoji li ijedan narod na zemlji kao tvoj izraelski narod radi kojega je Bog išao da ga izbavi sebi za narod da tako stečeš sebi ime velikim i strašnim čudesima, izgoneći krivobožačka plemena pred svojim narodom koji si otkupio iz Egipta?"},{"v":24,"t":"Tako si učinio svoj izraelski narod svojim narodom zauvijek, a ti si mu, Jahve, postao Bogom."},{"v":25,"t":"Zato sada, Gospode Jahve, ispuni zauvijek obećanje koje si dao svome sluzi i njegovu domu i učini kako si obrekao."},{"v":26,"t":"Neka se veliča tvoje ime zauvijek i neka se govori: Jahve nad vojskama jest Bog Izraelov, a dom sluge tvoga Davida neka stoji čvrsto pred tobom."},{"v":27,"t":"Jer si ti, Jahve nad vojskama, Bože Izraelov, objavio svome sluzi ovo: 'Ja ću ti podići dom.' Zato je tvoj sluga smogao hrabrosti da ti se pomoli ovom molitvom."},{"v":28,"t":"Uistinu, Gospode Jahve, ti si Bog, tvoje su riječi istinite i ti daješ ovo lijepo obećanje svome sluzi."},{"v":29,"t":"Udostoj se sada blagosloviti dom svoga sluge da ostane dovijeka pred tobom. Jer kad ti, Gospode Jahve, obrekneš i blagosloviš, kuća tvoga sluge bit će blagoslovljena zasvagda.”"}]},"8":{"hr":[{"v":1,"t":"Poslije toga David porazi Filistejce i pokori ih te ote Gat s njegovim selima iz filistejskih ruku."},{"v":2,"t":"Porazi i Moapce i izmjeri ih uzicom polegavši ih po zemlji: dvije uzice odmjeri onih koje treba pogubiti, a jednu punu uzicu onih koje treba ostaviti na životu. Tako Moapci postadoše Davidovi podanici koji su mu donosili danak."},{"v":3,"t":"David je porazio i Hadadezera, Rehobova sina, sopskoga kralja, kad je izišao da proširi svoju vlast do Rijeke."},{"v":4,"t":"David zarobi od njega tisuću i sedam stotina konjanika i dvadeset tisuća pješaka; ispresijecao je petne žile svim konjima od bojnih kola; ostavio ih je samo stotinu."},{"v":5,"t":"Damaščanski su Aramejci došli u pomoć Hadadezeru, sopskome kralju, ali je David pobio među Aramejcima dvadeset i dvije tisuće ljudi."},{"v":6,"t":"Postavio je namjesnike u Damaščanskom Aramu. Tako Aramejci postadoše Davidovi podanici i moradoše mu plaćati danak. Jahve je davao pobjedu Davidu kuda je god išao."},{"v":7,"t":"David zaplijeni zlatne štitove što ih imahu Hadadezerove sluge i donese ih u Jeruzalem."},{"v":8,"t":"Iz Tebaha i iz Berotaja, Hadadezerovih gradova, donese kralj David silni tuč."},{"v":9,"t":"Kad je čuo hamatski kralj Tou da je David porazio svu Hadadezerovu vojsku,"},{"v":10,"t":"poslao je svoga sina Hadorama kralju Davidu da ga pozdravi i da mu čestita što je vojevao protiv Hadadezera i porazio ga, jer je Hadadezer bio u ratu s Touom; Hadoram donese srebrnih, zlatnih i tučanih predmeta."},{"v":11,"t":"I njih kralj David posveti Jahvi sa srebrom i zlatom što ga bijaše uzeo od svih naroda koje je pokorio:"},{"v":12,"t":"od Aramaca, Moabaca, Amonaca, Filistejaca i od Amalečana te od plijena Hadadezera, Rehobova sina, kralja Sobe."},{"v":13,"t":"David steče novu slavu kad je na povratku porazio Edomce, u Slanoj dolini, osamnaest tisuća njih."},{"v":14,"t":"I postavi upravitelje u Edomu, i svi Edomci postadoše podanici Davidovi. I kuda je god David išao, Jahve mu davaše pobjedu."},{"v":15,"t":"David kraljevaše nad svim Izraelom, čineći pravo i pravicu svemu svome narodu."},{"v":16,"t":"Joab, sin Sarvijin, zapovijedaše vojskom, a Jošafat, sin Ahiludov, bijaše ljetopisac."},{"v":17,"t":"Sadok, sin Ahitubov, i Ebjatar, sin Ahimelekov, bijahu svećenici; Seraja bijaše državni pisar;"},{"v":18,"t":"Benaja, sin Jojadin, zapovijedaše Kerećanima i Pelećanima; Davidovi sinovi bijahu namjesnici."}]},"9":{"hr":[{"v":1,"t":"Jednoga dana upita David: “Ima li još koji preživjeli od Šaulove kuće da mu učinim milost zbog Jonatana?”"},{"v":2,"t":"A bijaše u Šaulovoj kući sluga po imenu Siba: njega dozvaše pred Davida i kralj ga zapita: “Jesi li ti Siba?” A on odgovori: “Jesam, tvoj sluga!”"},{"v":3,"t":"A kralj nastavi: “Zar nema više nikoga od Šaulove kuće da mu iskažem milost kao što je Božja milost?” A Siba odgovori kralju: “Ima još Jonatanov sin koji je hrom na obje noge.”"},{"v":4,"t":"Kralj ga upita: “Gdje je on?” A Siba odgovori kralju: “Eno ga u kući Makira, sina Amielova, u Lo Debaru.”"},{"v":5,"t":"Tada kralj David posla po njega u kuću Makira, sina Amielova, iz Lo Debara."},{"v":6,"t":"Kad je Meribaal, sin Jonatana, sina Šaulova, došao k Davidu, pade ničice i pokloni se. A David reče: “Meribaale!” On odgovori: “Evo tvoga sluge!”"},{"v":7,"t":"A David mu reče: “Ne boj se jer ti želim iskazati milost zbog tvoga oca Jonatana. Vratit ću ti sva polja tvoga djeda Šaula, a ti ćeš svagda jesti kruh za mojim stolom.”"},{"v":8,"t":"Meribaal se pokloni i reče: “Što je tvoj sluga te iskazuješ milost mrtvome psu kao što sam ja?”"},{"v":9,"t":"Potom kralj dozva Sibu, Šaulova slugu, i reče mu: “Sve što je pripadalo Šaulu i njegovoj kući, sve to dajem sinu tvoga gospodara."},{"v":10,"t":"Ti ćeš mu sa svojim sinovima i sa svojim slugama obrađivati zemlju, od nje ćeš skupljati žetvu da obitelj tvoga gospodara ima kruha; a Meribaal, sin tvoga gospodara, jest će svagda za mojim stolom.” A Siba imaše petnaest sinova i dvadeset slugu."},{"v":11,"t":"Siba odgovori kralju: “Tvoj će sluga učiniti sve što je moj gospodar i kralj zapovjedio svome sluzi.” Meribaal je, dakle, jeo za Davidovim stolom kao jedan između kraljevih sinova."},{"v":12,"t":"Meribaal je imao maloga sina po imenu Mika. A svi koji su živjeli u Sibinoj kući bijahu u službi Meribaala."},{"v":13,"t":"A Meribaal je boravio u Jeruzalemu, jer je uvijek jeo za kraljevim stolom. Bio je hrom na obje noge."}]},"10":{"hr":[{"v":1,"t":"Poslije toga umrije Nahaš, kralj Amonaca, a zakralji se njegov sin Hanun mjesto njega."},{"v":2,"t":"A David reče u sebi: “Želio bih iskazati ljubav Nahaševu sinu Hanunu, kao što je njegov otac iskazao meni.” Zato David posla svoje sluge da mu izraze sućut zbog njegova oca. Ali kad su Davidove sluge došle u zemlju Amonaca,"},{"v":3,"t":"rekoše knezovi Amonaca svome gospodaru Hanunu: “Zar misliš da je David poslao ljude da ti izraze sućut zato što bi htio iskazati čast tvome ocu? Nije li možda zato David poslao svoje ljude k tebi da razvide grad da bi doznao njegovu obranu i potom ga oborio?”"},{"v":4,"t":"Tada Hanun pograbi Davidove sluge, obrija im pola brade i skrati im haljine dopola, sve do zadnjice, i posla ih natrag."},{"v":5,"t":"Kad su to javili Davidu, posla on čovjeka pred njih, jer su ti ljudi bili teško osramoćeni, i poruči im: “Ostanite u Jerihonu dok vam ne naraste brada, pa se onda vratite!”"},{"v":6,"t":"Tada Amonci uvidješe da su se omrazili s Davidom; zato Amonci poslaše glasnike da za plaću unajme Aramejce iz Bet Rehoba i Aramejce iz Sobe, dvadeset tisuća pješaka, zatim kralja Maake, tisuću ljudi, i ljude iz Toba, dvanaest tisuća vojnika."},{"v":7,"t":"Kad je David to čuo, posla Joaba s vojskom i izabranim junacima."},{"v":8,"t":"Amonci iziđoše i svrstaše se u bojni red pred gradskim vratima, dok su Aramejci iz Sobe i iz Rehoba i ljudi iz Toba i iz Maake stajali zasebno na polju."},{"v":9,"t":"Vidjevši postavljene bojne redove prema sebi sprijeda i straga, probra Joab najvrsnije među Izraelcima i svrsta ih prema Aramejcima."},{"v":10,"t":"Ostalu vojsku predade bratu Abišaju da je svrsta prema Amoncima."},{"v":11,"t":"I reče mu: “Ako Aramejci budu jači od mene, onda ti meni priskoči u pomoć; ako Amonci budu jači od tebe, ja ću tebi pohrliti u pomoć."},{"v":12,"t":"Budi hrabar i junački se držimo radi naroda i radi gradova svoga Boga; a Jahve neka učini što je dobro u njegovim očima.”"},{"v":13,"t":"Tada se Joab i vojska koja je bila s njim počeše primicati da udare na Aramejce, ali oni pobjegoše pred njima."},{"v":14,"t":"Kad su Amonci vidjeli da su Aramejci pobjegli, umakoše i oni ispred Abišaja i povukoše se u grad. Tada Joab odustane od rata protiv Amonaca i vrati se u Jeruzalem."},{"v":15,"t":"Kad su Aramejci vidjeli gdje su ih Izraelci razbili, sabraše ponovo svoje čete."},{"v":16,"t":"Hadadezer posla glasnike i sabra Aramejce što su s one strane rijeke. Ovi dođoše u Helam pod vodstvom Šobaka, vojvode Hadadezerove vojske."},{"v":17,"t":"Pošto su to javili Davidu, on skupi sve Izraelce i, prešavši preko Jordana, dođe u Helam. Aramejci se svrstaše protiv Davida i zametnuše s njime boj."},{"v":18,"t":"Ali Aramejci udariše u bijeg ispred Izraelaca i David im pobi sedam stotina konja od bojnih kola i četrdeset tisuća pješaka; pogubi i njihova vojvodu Šobaka te je ondje umro."},{"v":19,"t":"A kad svi kraljevi, Hadadezerovi vazali, vidješe da ih je razbio Izrael, sklopiše mir s Izraelom i počeše mu služiti. A Aramejci se više nisu usuđivali pomagati Amoncima."}]},"11":{"hr":[{"v":1,"t":"U početku slijedeće godine, u doba kad kraljevi izlaze u rat, posla David Joaba i s njim svoje ljude i svega Izraela: oni pobiše Amonce i podsjedoše Rabu. A David osta u Jeruzalemu."},{"v":2,"t":"A jednoga dana predveče usta David sa svoje postelje i prošeta se po krovu svoje palače. Opazi s krova ženu gdje se kupa. Ta žena bijaše izvanredno lijepa."},{"v":3,"t":"David se propita za tu ženu i rekoše mu: “Pa to je Bat-Šeba, kći Eliamova i žena Urije Hetita!”"},{"v":4,"t":"Nato David posla glasnika da je dovedu k njemu. Kad je došla, leže on s njom, upravo kad se bila očistila od svoje nečistoće. Zatim se ona vrati svojoj kući."},{"v":5,"t":"Žena zatrudnje te poruči Davidu: “Trudna sam!”"},{"v":6,"t":"Tada David posla poruku Joabu: “Pošalji k meni Uriju Hetita!” I Joab posla Uriju k Davidu."},{"v":7,"t":"Kad je Urija došao k njemu, zapita ga David kako je Joab, kako je vojska i kako napreduje rat."},{"v":8,"t":"Potom David reče Uriji: “Siđi u svoju kuću i operi svoje noge!” Urija iziđe iz kraljeva dvora, a za njim ponesoše dar s kraljeva stola."},{"v":9,"t":"Ali Urija osta da spava pred vratima kraljeva dvora sa stražarima svoga gospodara i ne ode svojoj kući."},{"v":10,"t":"Javiše to Davidu govoreći: “Urija nije otišao svojoj kući!” Tada David upita Uriju: “Zar nisi došao s puta? Zašto ne ideš svojoj kući?”"},{"v":11,"t":"A Urija odgovori Davidu: “Kovčeg, Izrael i Juda borave pod šatorima, moj gospodar Joab i straža moga gospodara borave na otvorenu polju, a ja da uđem u svoju kuću da jedem i da pijem i da spavam sa svojom ženom? Živoga mi Jahve, i tako mi tvoga života, zaista neću učiniti nešto takvo!”"},{"v":12,"t":"Tada David reče Uriji: “Ostani još danas ovdje, a sutra ću te otpustiti.” Tako Urija osta u Jeruzalemu onaj dan."},{"v":13,"t":"Sutradan David pozva Uriju da jede i da pije pred njim i on ga opi. A uvečer Urija iziđe i leže na svoju postelju sa stražama svoga gospodara, ali svojoj kući nije otišao."},{"v":14,"t":"Ujutro David napisa pismo Joabu i posla ga po Uriji."},{"v":15,"t":"A u tom pismu pisao je ovako: “Postavite Uriju naprijed, gdje je najžešći boj, pa uzmaknite iza njega: neka bude pogođen i neka pogine!”"},{"v":16,"t":"Zato Joab, opsjedajući grad, postavi Uriju na mjesto gdje je znao da stoje najhrabriji ratnici."},{"v":17,"t":"Kad su onda građani provalili van i pobili se s Joabom, pade nekoliko od njegove vojske, od Davidovih ljudi, a pogibe i Urija Hetit."},{"v":18,"t":"Potom Joab posla čovjeka i javi Davidu sve što se dogodilo u boju."},{"v":19,"t":"I zapovjedi glasniku ovako: “Kad pripovjediš kralju sve što se dogodilo u boju,"},{"v":20,"t":"možda će se kralj razljutiti pa ti kazati: 'Zašto ste se primakli tako blizu gradu da navalite? Zar niste znali da se obično izmeću strijele sa zida?"},{"v":21,"t":"Tko je ubio Abimeleka, sina Jerubaalova? Nije li jedna žena bacila na njega mlinski kamen, ozgo sa zida, te je poginuo u Tebesu? Zašto ste se primakli tako blizu zidu?' Ako ti tako kaže, a ti mu reci: 'Poginuo je i tvoj sluga Urija Hetit.'”"},{"v":22,"t":"Glasnik krenu na put, dođe k Davidu i pripovjedi mu sve što mu je naložio Joab. A David planu gnjevom na Joaba i reče glasniku: “Zašto ste se primakli tako blizu zidu? Tko je ubio Abimeleka, sina Jerubaalova? Nije li jedna žena bacila na njega mlinski kamen, ozgo sa zida, te je poginuo u Tebesu? Zašto ste se primakli tako blizu zidu?”"},{"v":23,"t":"Glasnik odgovori Davidu: “Ti su ljudi silovito udarali na nas i izašli su protiv nas na otvoreno polje. Mi smo ih potisnuli natrag do gradskih vrata,"},{"v":24,"t":"ali su strijelci sa zida stali izmetati strijele na tvoje ljude te ih je poginulo nekoliko između kraljevih slugu; tako je poginuo i tvoj sluga Urija Hetit.”"},{"v":25,"t":"Tada David reče glasniku: “Ovako reci Joabu: 'Nemoj to uzimati toliko k srcu, jer mač proždire sad ovoga, sad onoga. Udaraj još jače na grad i obori ga!' Tako ćeš mu vratiti srčanost!”"},{"v":26,"t":"Kad je Urijina žena čula da je poginuo njezin muž Urija, žalila je za svojim mužem."},{"v":27,"t":"A kad je prošlo vrijeme žalosti, posla David po nju i uze je u svoj dvor, i ona mu posta ženom. I rodi mu sina. Ali djelo koje učini David bijaše zlo u očima Jahvinim."}]},"12":{"hr":[{"v":1,"t":"Jahve posla proroka Natana k Davidu. On uđe k njemu i reče mu: “U nekom gradu živjela dva čovjeka, jedan bogat, a drugi siromašan."},{"v":2,"t":"Bogati imaše ovaca i goveda u obilju."},{"v":3,"t":"A siromah nemaše ništa, osim jedne jedine ovčice koju bijaše kupio. Hranio ju je i ona je rasla kraj njega i s njegovom djecom; jela je od njegova zalogaja, pila iz njegove čaše; spavala ja na njegovu krilu: bila mu je kao kći."},{"v":4,"t":"I dođe putnik k bogatom čovjeku, a njemu bilo žao uzeti od svojih ovaca ili goveda da zgotovi gostu koji mu je došao. On ukrade ovčicu siromaha i zgotovi je za svog pohodnika.”"},{"v":5,"t":"Tada David planu žestokim gnjevom na toga čovjeka i reče Natanu: “Tako mi živog Jahve, smrt je zaslužio čovjek koji je to učinio!"},{"v":6,"t":"Četverostruko će naknaditi ovcu zato što je učinio to djelo i što nije znao milosrđa!”"},{"v":7,"t":"Tada Natan reče Davidu: “Ti si taj čovjek! Ovako govori Jahve, Bog Izraelov: 'Ja sam te pomazao za kralja nad Izraelom, ja sam te izbavio iz Šaulove ruke."},{"v":8,"t":"Predao sam ti kuću tvoga gospodara, položio sam žene tvoga gospodara na tvoje krilo, dao sam ti dom Izraelov i dom Judin; a ako to nije dosta, dodat ću ti još ovo ili ono."},{"v":9,"t":"Zašto si prezreo Jahvu i učinio ono što je zlo u njegovim očima? Ubio si mačem Uriju Hetita, a njegovu si ženu uzeo za svoju ženu. Jest, njega si ubio mačem Amonaca."},{"v":10,"t":"Zato se neće nikada više okrenuti mač od tvoga doma, jer si me prezreo i jer si uzeo ženu Urije Hetita da ti bude žena.'"},{"v":11,"t":"Ovako govori Jahve: 'Evo ja ću podići na te zlo iz tvoga doma. Uzet ću tvoje žene ispred tvojih očiju i dat ću ih tvome bližnjemu, koji će spavati s tvojim ženama na vidiku ovome suncu."},{"v":12,"t":"Ti si doduše radio tajno, ali ja ću ovu prijetnju izvršiti pred svim Izraelom i pred ovim suncem!'”"},{"v":13,"t":"Tada David reče Natanu: “Sagriješio sam protiv Jahve!” A Natan odvrati Davidu: “Jahve ti oprašta tvoj grijeh: nećeš umrijeti."},{"v":14,"t":"Ali jer si tim djelom prezreo Jahvu, neminovno će umrijeti dijete koje ti se rodilo!”"},{"v":15,"t":"Potom Natan ode svojoj kući. A Jahve udari dijete koje je Urijina žena rodila Davidu i ono se teško razbolje."},{"v":16,"t":"David se molitvom obrati Bogu za dijete: postio je, vraćao se kući i ležao preko noći na goloj zemlji, pokriven vrećom."},{"v":17,"t":"A starješine njegova doma stajahu oko njega da ga podignu sa zemlje, ali on ne htjede i ne okusi s njima nikakva jela."},{"v":18,"t":"A sedmi dan umrije dijete. Davidovi dvorani ne usudiše se javiti mu da je dijete umrlo. Jer mišljahu: “Dok je dijete bilo živo, govorili smo mu, a on nas nije htio slušati. A kako ćemo mu kazati da je dijete umrlo? Učinit će zlo!”"},{"v":19,"t":"A David opazi da njegovi dvorani šapću među sobom i on shvati da je dijete umrlo. I upita David svoje dvorane: “Je li dijete umrlo?” A oni odgovoriše: “Umrlo je.”"},{"v":20,"t":"Tada David usta sa zemlje, okupa se, pomaza se i preobuče se u druge haljine. Zatim uđe u Dom Jahvin i pokloni se. Vrativši se potom svojoj kući, zatraži da mu dadu jela; i jeo je."},{"v":21,"t":"A njegovi dvorani upitaše ga: “Što to radiš? Dok je dijete bilo živo, postio si i plakao; a sada, kad je dijete umrlo, ustaješ i jedeš!”"},{"v":22,"t":"A on odgovori: “Dok je dijete bilo živo, postio sam i plakao jer sam mislio: 'Tko zna? Jahve će se možda smilovati na me i dijete će ostati živo!'"},{"v":23,"t":"A sada, kad je umrlo, čemu da postim? Mogu li ga vratiti? Ja ću otići k njemu, ali se ono neće vratiti k meni!”"},{"v":24,"t":"Potom David utješi svoju ženu Bat-Šebu. Dođe k njoj i leže s njom. Ona zatrudnje i rodi sina komu nadjenu ime Salomon. Jahve ga zamilova"},{"v":25,"t":"i objavi to po proroku Natanu. Ovaj ga nazva imenom Jedidja, po riječi Jahvinoj."},{"v":26,"t":"Joab navali na Rabu sinova Amonovih i osvoji kraljevski grad."},{"v":27,"t":"Tada Joab posla glasnika k Davidu s porukom: “Ja sam navalio na Rabu i osvojio grad uz vodu."},{"v":28,"t":"Sada ti saberi ostalu vojsku, opkoli grad i osvoji ga, da ne bih ja osvojio grada i dao mu svoje ime.”"},{"v":29,"t":"I skupi David svu vojsku, krenu na Rabu, navali na grad i zauze ga."},{"v":30,"t":"Ondje skinu s Malkomove glave krunu, koja bijaše teška jedan zlatni talenat; u njoj je bio dragi kamen, koji posta ures na Davidovoj glavi. I vrlo bogat plijen odnese iz grada."},{"v":31,"t":"A narod koji bijaše u njemu izvede i stavi ga da radi kod pila, željeznim pijucima i željeznim sjekirama i upotrijebi ga za rad u ciglanama. I tako je isto činio svim gradovima sinova Amonovih. Potom se David sa svom vojskom vrati u Jeruzalem."}]},"13":{"hr":[{"v":1,"t":"A potom se dogodi ovo: Davidov sin Abšalom imao je lijepu sestru po imenu Tamaru i u nju se zaljubio Davidov sin Amnon."},{"v":2,"t":"Amnon se toliko mučio da se gotovo razbolio radi svoje sestre Tamare: jer ona bijaše djevica, pa Amnon nije vidio mogućnosti da joj učini bilo što."},{"v":3,"t":"Ali imaše Amnon prijatelja po imenu Jonadaba, sina Davidova brata Šimeja; a Jonadab bijaše vrlo domišljat."},{"v":4,"t":"I upita on Amnona: “Odakle to, kraljev sine, da si svako jutro mlitav? Ne bi li mi kazao?” A Amnon mu odgovori: “Zaljubljen sam u Tamaru, sestru svoga brata Abšaloma.”"},{"v":5,"t":"A Jonadab mu reče: “Lezi u postelju i pričini se bolestan, pa kad dođe tvoj otac da te pohodi, ti mu reci: 'Dopusti da dođe moja sestra Tamara da mi dade jesti; ako ona pred mojim očima zgotovi jelo da to vidim, onda ću iz njezine ruke jesti.'”"},{"v":6,"t":"Amnon, dakle, leže i pričini se bolestan. Kad je došao kralj da ga pohodi, reče Amnon kralju: “Dopusti da dođe moja sestra Tamara da pred mojim očima zgotovi koji kolač i ja ću se okrijepiti iz njezine ruke.”"},{"v":7,"t":"Tada David poruči Tamari u palaču: “Idi u kuću svoga brata Amnona i priredi mu jelo!”"},{"v":8,"t":"Tamara ode u kuću svoga brata Amnona. A on ležaše. Uze ona brašna, umijesi ga, načini kolače pred njegovim očima te ih ispeče."},{"v":9,"t":"Potom uze tavu i istrese je preda nj, ali Amnon ne htjede jesti nego reče: “Otpremite sve odavde!” I svi iziđoše od njega."},{"v":10,"t":"Tada Amnon reče Tamari: “Donesi mi jelo u spavaonicu da se okrijepim iz tvoje ruke!” I Tamara uze kolače koje bijaše zgotovila i donese ih svome bratu Amnonu u spavaonicu."},{"v":11,"t":"A kad mu je pružila da jede, on je uhvati rukom i reče joj: “Dođi, sestro moja, lezi sa mnom!”"},{"v":12,"t":"A ona mu reče: “Nemoj, brate moj! Ne sramoti me jer se tako ne radi u Izraelu. Ne čini takve sramote!"},{"v":13,"t":"Kuda bih ja sa svojom sramotom? A i ti bi bio kao bestidnik u Izraelu! Nego govori s kraljem: on me neće uskratiti tebi!”"},{"v":14,"t":"Ali je on ne htjede poslušati, nego je svlada i leže s njom."},{"v":15,"t":"Nato je odmah zamrzi silnom mržnjom te je mržnja kojom ju je zamrzio bila veća od ljubavi kojom ju je prije ljubio. I reče joj Amnon: “Ustani! Odlazi!”"},{"v":16,"t":"A ona mu odvrati: “Ne, brate moj! Ako me sad otjeraš, bit će to veće zlo od onoga koje si mi učinio!” Ali je on ne htjede slušati,"},{"v":17,"t":"nego dozva momka koji ga je služio i zapovjedi mu: “Otjeraj ovu od mene, izbaci je i zaključaj vrata za njom!”"},{"v":18,"t":"(A ona je imala na sebi haljinu s dugim rukavima, jer su se nekoć u takve haljine oblačile kraljeve kćeri dok su bile djevojke.) Sluga je izvede van i zaključa vrata za njom."},{"v":19,"t":"Tada Tamara uze prašine i posu se njom po glavi, razdrije haljinu s dugim rukavima koju je imala na sebi, stavi ruku na glavu i ode vičući glasno dok je išla."},{"v":20,"t":"A njezin je brat Abšalom upita: “Je li možda tvoj brat Amnon bio s tobom? Ali sada, sestro moja, šuti: brat ti je! Ne uzimaj to k srcu!” Tako je Tamara ostala osamljena u kući svoga brata Abšaloma."},{"v":21,"t":"Kad je kralj David čuo sve što se dogodilo, vrlo se razgnjevi, ali ne htjede žalostiti svoga sina Amnona, koga je ljubio jer mu bijaše prvorođenac."},{"v":22,"t":"A Abšalom ne reče Amnonu ni riječi, ni zle ni dobre, jer je Abšalom zamrzio Amnona što mu osramoti sestru Tamaru."},{"v":23,"t":"A poslije dvije godine imao je Abšalom striženje ovaca u Baal Hasoru kod Efrajima; i Abšalom pozva svu kraljevu obitelj."},{"v":24,"t":"Abšalom dođe kralju i reče mu: “Evo, tvoj sluga ima striženje ovaca, pa neka se kralj i njegovi dvorani udostoje doći svome sluzi.”"},{"v":25,"t":"Ali kralj odgovori Abšalomu: “Ne, sine, nećemo doći svi, da ti ne budemo na teret.” Abšalom ustraja, ali kralj ne htjede ići, nego ga blagoslovi i otpusti."},{"v":26,"t":"Ali Abšalom nastavi: “Ako ti nećeš, dopusti da bar moj brat Amnon pođe s nama.” A kralj ga upita: “Zašto da ide s tobom?”"},{"v":27,"t":"Ali je Abšalom i dalje navaljivao te David naposljetku pusti s njim Amnona i sve kraljeve sinove. Abšalom priredi kraljevsku gozbu"},{"v":28,"t":"i zapovjedi svojim slugama ovako: “Pazite! Kad se Amnonu razveseli srce od vina i ja vam viknem: 'Ubijte Amnona!' tada ga pogubite! Ne bojte se, jer vam tako zapovijedam! Ohrabrite se i pokažite se junaci!”"},{"v":29,"t":"I Abšalomove sluge učiniše s Amnonom kako im zapovjedi Abšalom. Tada skočiše svi kraljevi sinovi, pojahaše svaki svoju mazgu i pobjegoše."},{"v":30,"t":"Dok su oni još bili na putu, dođe ovakva vijest Davidu: “Abšalom je pobio sve kraljeve sinove, nije ostao od njih ni jedan jedini.”"},{"v":31,"t":"Kralj ustade, razdrije svoje haljine i baci se na zemlju; i svi njegovi dvorani koji stajahu oko njega razdriješe svoje haljine."},{"v":32,"t":"Ali Jonadab, sin Davidova brata Šimeja, progovori ovako: “Neka ne govori moj gospodar da su pobili sve mladiće, kraljeve sinove, jer je poginuo samo Amnon: na Abšalomovu licu mogla se predviđati nesreća od onoga dana kad je Amnon osramotio njegovu sestru Tamaru."},{"v":33,"t":"Zato neka sada moj gospodar i kralj ne misli u srcu da su svi kraljevi sinovi poginuli. Poginuo je samo Amnon,"},{"v":34,"t":"a Abšalom je pobjegao.” A momak koji bijaše na straži podiže oči i ugleda mnoštvo naroda gdje silazi cestom od Horonajima. Stražar dođe i javi kralju: “Vidio sam ljude gdje silaze cestom od Horonajima po gorskom obronku.”"},{"v":35,"t":"Tada Jonadab reče kralju: “Evo stigoše kraljevi sinovi! Dogodilo se kako je rekao tvoj sluga.”"},{"v":36,"t":"Tek što je to izrekao, a to kraljevi sinovi uđoše i zaplakaše u sav glas; a i kralj i svi njegovi dvorani plakahu."},{"v":37,"t":"Abšalom pak bijaše pobjegao i otišao k Talmaju, sinu Amihudovu, gešurskom kralju. A David tugovaše za svojim sinom bez prestanka."},{"v":38,"t":"A pošto je Abšalom pobjegao i otišao u Gešur, ostao je ondje tri godine."},{"v":39,"t":"Kralj David prestao se srditi na Abšaloma jer se utješio zbog smrti Amnonove."}]},"14":{"hr":[{"v":1,"t":"A Joab, sin Sarvijin, opazi da se kraljevo srce okreće k Abšalomu."},{"v":2,"t":"Zato Joab pošalje u Tekou po jednu pametnu ženu i reče joj: “Učini se kao da si u žalosti za mrtvim, obuci žalobne haljine, nemoj se mazati uljem, nego budi kao žena koja je već dugo vremena u žalosti za mrtvim."},{"v":3,"t":"Otići ćeš kralju i govorit ćeš mu ovako.” I Joab je nauči što će govoriti."},{"v":4,"t":"Žena iz Tekoe ode kralju, pade ničice na zemlju i pokloni se, zatim reče: “Pomozi, kralju!”"},{"v":5,"t":"Kralj je upita: “Što ti je?” A ona odgovori: “Ah, ja sam udovica. Muž mi je umro,"},{"v":6,"t":"a tvoja je službenica imala dva sina. Oni se posvadiše u polju, a nije bilo nikoga da ih razdvoji te je jedan od njih udario svoga brata i ubio ga."},{"v":7,"t":"I sad se podiže sav rod na tvoju službenicu i reče: 'Predaj nam toga što je ubio svoga brata: mi ćemo ga pogubiti za život njegova brata koga je ubio, a time ćemo zatrti i baštinika.' Tako hoće da ugase žeravicu koja mi je ostala, da ne ostave mome mužu ni imena ni potomstva na zemlji.”"},{"v":8,"t":"A kralj reče ženi: “Idi svojoj kući, ja ću odrediti što treba za te.”"},{"v":9,"t":"A žena iz Tekoe reče kralju: “Gospodaru kralju! Neka na me i na moj očinski dom padne krivica; kralj i njegovo prijestolje nedužni su u tome!”"},{"v":10,"t":"A kralj nastavi: “Onoga koji ti se zaprijetio dovedi k meni! Taj te neće više dirnuti!”"},{"v":11,"t":"A ona reče: “Neka se kralj udostoji spomenuti ime Jahve, svoga Boga, da krvni osvetnik neće umnožiti zator i da neće pogubiti moga sina!” A on obeća: “Tako mi živog Jahve, nijedna vlas neće pasti s glave tvome sinu!”"},{"v":12,"t":"A žena nastavi: “Dopusti da tvoja službenica kaže jednu riječ svome gospodaru kralju.” A on odvrati: “Govori!”"},{"v":13,"t":"A žena reče: “Dakle, zašto je kralj - jer se izričući ovakvu presudu sam priznao krivim - donio protiv naroda Božjega odluku da ne pušta kući onoga koga je prognao?"},{"v":14,"t":"Mi smo svi osuđeni na smrt, slični smo vodi koja se prolije na zemlju i više se ne može skupiti, i Bog ne podiže mrtvaca: neka, dakle, kralj misli na to da prognanik ne ostane izagnan daleko od njega."},{"v":15,"t":"A razlog zašto sam došla da iznesem pred svoga gospodara kralja ovu stvar bio je taj što su me zaplašili ljudi, pa je mislila tvoja službenica: moram govoriti s kraljem, možda će kralj učiniti ono što mu njegova službenica kaže."},{"v":16,"t":"Jer će kralj poslušati svoju službenicu i izbaviti je iz ruku čovjeka koji hoće da me istrijebi zajedno s mojim sinom iz Božje baštine."},{"v":17,"t":"Zato je tvoja službenica pomislila: neka mi riječ moga gospodara i kralja bude na umirenje. Jer moj je gospodar i kralj kao Božji anđeo koji sluša dobro i zlo. Jahve, tvoj Bog, neka bude s tobom!”"},{"v":18,"t":"Tada progovori kralj i reče ženi: “Nemoj mi sada zatajiti ono što ću te pitati!” A žena odgovori: “Neka govori moj gospodar kralj!”"},{"v":19,"t":"Tada kralj upita: “Nisu li Joabovi prsti s tobom u svemu tome?” A žena odgovori: “Tako bio živ, gospodaru kralju, zaista se ne može ni desno ni lijevo od svega što je kazao moj gospodar i kralj! Jest, tvoj mi je sluga Joab zapovjedio, on je naučio tvoju službenicu sve ove riječi."},{"v":20,"t":"Tvoj je sluga Joab to učinio da bi svemu dao drugo lice, ali je moj gospodar mudar kao Božji anđeo, on zna sve što se zbiva na zemlji.”"},{"v":21,"t":"Tada se kralj okrenu Joabu i reče mu: “Dobro, učinit ću to. Idi i dovedi natrag mladića Abšaloma!”"},{"v":22,"t":"A Joab pade licem na zemlju, pokloni se i zahvali kralju; zatim reče Joab: “Danas vidi tvoj sluga da je našao milost u tvojim očima, gospodaru kralju, kad je kralj ispunio molbu svoga sluge.”"},{"v":23,"t":"Potom se diže Joab, ode u Gešur i dovede Abšaloma natrag u Jeruzalem."},{"v":24,"t":"Ali kralj reče: “Neka ide u svoju kuću, a meni neka ne dolazi na oči!” I Abšalom se povuče u svoju kuću i ne dođe kralju na oči."},{"v":25,"t":"U svemu Izraelu ne bijaše čovjeka tako lijepa kao Abšalom komu bi se mogle izreći tolike pohvale: od pete do glave nije bilo na njemu mane."},{"v":26,"t":"A kad bi šišao kosu - a šišao ju je na koncu svake godine, jer mu je bila preteška pa ju je morao šišati - mjerio bi svoju kosu: bila bi teška dvije stotine šekela, po kraljevskoj mjeri."},{"v":27,"t":"Abšalomu se rodiše tri sina i jedna kći po imenu Tamara; bila je to vrlo lijepa žena."},{"v":28,"t":"Abšalom provede dvije godine u Jeruzalemu a da nije došao kralju na oči."},{"v":29,"t":"Tada Abšalom pozva Joaba k sebi da bi ga poslao kralju, ali Joab ne htjede doći k njemu; i posla drugi put po njega, ali on opet ne htjede doći."},{"v":30,"t":"Tada Abšalom zapovjedi slugama: “Znate Joabovo polje koje je pokraj mojega i na kojem raste ječam: idite i zapalite ga!” I Abšalomove sluge zapališe ono polje."},{"v":31,"t":"Tada se diže Joab, dođe k Abšalomu u kuću i upita ga: “Zašto su tvoje sluge zapalile moje polje?”"},{"v":32,"t":"A Abšalom odgovori Joabu: “Ja sam poslao k tebi i poručio ti: 'Dođi ovamo, želio bih te poslati kralju s ovom porukom: Zašto sam se vratio iz Gešura?' Bolje bi bilo za mene da sam još ondje. Zato sad hoću da dođem kralju na oči, pa ako ima na meni kakva krivica, neka me pogubi!”"},{"v":33,"t":"Joab ode kralju i javi mu te riječi. Zatim kralj pozva Abšaloma. Dođe on pred kralja, pokloni mu se i pade ničice pred kralja. I kralj poljubi Abšaloma."}]},"15":{"hr":[{"v":1,"t":"Poslije toga nabavi Abšalom sebi kola i konje i pedeset ljudi koji su trčali pred njim."},{"v":2,"t":"Abšalom je u rano jutro stajao kraj puta koji vodi do gradskih vrata; i tko god je imao kakvu parnicu te išao kralju na sud, Abšalom bi ga dozvao k sebi i pitao: “Iz kojega si grada?” A kad bi ovaj odgovorio: “Tvoj je sluga iz toga i toga Izraelova plemena”,"},{"v":3,"t":"tada bi mu Abšalom rekao: “Vidiš, tvoja je stvar dobra i pravedna, ali nećeš naći nikoga koji bi te saslušao kod kralja.”"},{"v":4,"t":"Abšalom bi nastavljao: “Ah, kad bi mene postavili za suca u zemlji! Svaki bi koji ima kakvu parnicu ili sud dolazio k meni i ja bih mu pribavio pravo!”"},{"v":5,"t":"A kad bi mu se tko približio da mu se pokloni, on bi pružio ruku, privukao ga k sebi i poljubio."},{"v":6,"t":"Tako je činio Abšalom svim Izraelcima koji su dolazili na sud kralju. Time je Abšalom predobivao srca Izraelaca za sebe."},{"v":7,"t":"Kad su prošle četiri godine, Abšalom reče kralju: “Dopusti da odem u Hebron i da izvršim zavjet kojim sam se zavjetovao Jahvi."},{"v":8,"t":"Jer kad bijah u Gešuru u Aramu, tvoj se sluga zavjetovao ovako: 'Ako me Jahve dovede natrag u Jeruzalem, iskazat ću čast Jahvi u Hebronu.'”"},{"v":9,"t":"A kralj mu odgovori: “Idi u miru!” I on krenu na put i ode u Hebron."},{"v":10,"t":"Abšalom razasla tajne glasnike po svim Izraelovim plemenima i poruči im: “Kad čujete zvuk roga, tada recite: Abšalom je postao kralj u Hebronu.”"},{"v":11,"t":"A ode s Abšalomom dvije stotine ljudi iz Jeruzalema; bijahu to uzvanici koji su bezazleno pošli ne znajući što se sprema."},{"v":12,"t":"Abšalom posla i po Gilonjanina Ahitofela, Davidova savjetnika, iz njegova grada Gilona, da pribiva prinošenju žrtava. Urota je bila jaka, a mnoštvo Abšalomovih pristaša sve je više raslo."},{"v":13,"t":"Tada stiže Davidu glasnik te mu javi: “Srce Izraelaca priklonilo se Abšalomu.”"},{"v":14,"t":"Tada David reče svim svojim dvoranima koji bijahu s njim u Jeruzalemu: “Ustanite! Bježimo! Inače nećemo uteći od Abšaloma. Pohitite brzo, da on ne bude brži i ne stigne nas, da ne obori na nas zlo i ne pobije grada oštricom mača!”"},{"v":15,"t":"A kraljevi dvorani odgovoriše kralju: “Što god odluči naš gospodar kralj, evo tvojih slugu!”"},{"v":16,"t":"I kralj iziđe pješice sa svim svojim dvorom; ipak ostavi kralj deset inoča da čuvaju palaču."},{"v":17,"t":"I kralj ode pješice sa svim narodom i zaustavi se kod posljednje kuće."},{"v":18,"t":"Svi njegovi dvorani stajahu uza nj. Tada svi Kerećani, svi Pelećani, Itaj i svi Gićani koji bijahu došli s njim iz Gata, šest stotina ljudi, prođoše pred kraljem."},{"v":19,"t":"Kralj upita Itaja Gićanina: “Zašto i ti ideš s nama? Vrati se i ostani kod kralja! Ti si stranac, prognan iz svoje zemlje."},{"v":20,"t":"Jučer si došao, a danas da te vodim da se potucaš s nama kad ja idem kamo me sreća nanese. Vrati se i odvedi svoju braću natrag sa sobom, a Jahve neka ti iskaže ljubav i vjernost!”"},{"v":21,"t":"Ali Itaj odgovori kralju ovako: “Živoga mi Jahve i tako mi živ bio moj gospodar kralj: gdje god bude moj gospodar kralj, bilo na smrt ili na život, ondje će biti i tvoj sluga!”"},{"v":22,"t":"Tada David reče Itaju: “Hajde, prođi!” I Itaj iz Gata prođe sa svim svojim ljudima i sa svom svojom pratnjom."},{"v":23,"t":"Svi plakahu iza glasa. Kralj je stajao na potoku Kidronu i sav je narod prolazio pred njim prema pustinji."},{"v":24,"t":"Bijaše ondje i Sadok i s njim svi leviti koji su nosili Kovčeg Božji. I oni spustiše Kovčeg Božji kraj Ebjatara dok sav narod nije izišao iz grada."},{"v":25,"t":"Tada kralj reče Sadoku: “Odnesi Kovčeg Božji natrag u grad. Ako nađem milost u Jahve, on će me dovesti natrag i dopustiti mi da opet vidim njega i njegovo prebivalište."},{"v":26,"t":"A ako rekne ovako: 'Nisi mi po volji!' - onda evo me, neka čini sa mnom što je dobro u njegovim očima!”"},{"v":27,"t":"Još kralj reče svećeniku Sadoku: “Hajde, ti i Ebjatar vratite se u miru u grad, i vaša dva sina s vama, tvoj sin Ahimaas i Ebjatarov sin Jonatan."},{"v":28,"t":"Evo, ja ću se zadržati na ravnicama pustinje dok ne dođe od vas glas da me obavijesti.”"},{"v":29,"t":"Nato Sadok i Ebjatar odnesoše Kovčeg Božji natrag u Jeruzalem i ostadoše ondje."},{"v":30,"t":"David se uspinjao na Maslinsku goru, sve plačući, pokrivene glave i bos, i sav narod koji ga je pratio iđaše pokrivene glave i plačući."},{"v":31,"t":"Tada javiše Davidu da je i Ahitofel među urotnicima s Abšalomom. A David zavapi: “Obezumi Ahitofelove savjete, Jahve!”"},{"v":32,"t":"Kad je David došao na vrh gore, ondje gdje se klanja Bogu, dođe mu u susret Hušaj Arčanin, prijatelj Davidov, razdrte haljine i glave posute prahom."},{"v":33,"t":"David mu reče: “Ako pođeš sa mnom, bit ćeš mi na teret."},{"v":34,"t":"Ali ako se vratiš u grad i kažeš Abšalomu: 'Bit ću tvoj sluga, gospodaru kralju; prije sam služio tvome ocu, a sada ću služiti tebi', moći ćeš tada okretati Ahitofelove savjete u moju korist."},{"v":35,"t":"S tobom će biti i svećenici Sadok i Ebjatar. Sve što čuješ iz palače, javi svećenicima Sadoku i Ebjataru."},{"v":36,"t":"S njima su ondje i dva njihova sina, Ahimaas Sadokov i Jonatan Ebjatarov: po njima mi javljajte sve što čujete.”"},{"v":37,"t":"Tako se Hušaj, prijatelj Davidov, vrati u grad upravo u času kad je Abšalom ulazio u Jeruzalem."}]},"16":{"hr":[{"v":1,"t":"Kad je David prešao malo preko vrha, dođe mu u susret Siba, sluga Meribaalov, sa dva osamarena magarca koja su nosila dvije stotine kruhova, sto grozdova suhog grožđa, sto voćnjača i mijeh vina."},{"v":2,"t":"Kralj upita Sibu: “Što ćeš s tim?” A Siba odgovori: “Magarci će poslužiti kraljevoj obitelji za jahanje, kruh i voće momcima za jelo, a vino za piće onima koji se umore u pustinji.”"},{"v":3,"t":"Kralj dalje upita: “A gdje je sin tvoga gospodara?” A Siba odgovori kralju: “Eno, ostao je u Jeruzalemu jer je mislio: 'Danas će mi dom Izraelov vratiti kraljevstvo moga oca.'”"},{"v":4,"t":"Tada kralj reče Sibi: “Sve što posjeduje Meribaal neka je tvoje.” A Siba odgovori: “Bacam se ničice pred tobom. O, da bih i dalje bio dostojan milosti u tvojim očima, kralju gospodaru!”"},{"v":5,"t":"Kad je kralj David došao do Bahurima, izađe odande čovjek od roda Šaulova. Zvao se Šimej, a bio je sin Gerin. Dok je izlazio, neprestano je proklinjao."},{"v":6,"t":"Bacao je kamenje na Davida i na sve dvorane kralja Davida, premda je sva vojska sa svim junacima okruživala kralja s desne i lijeve strane."},{"v":7,"t":"A Šimej je ovako govorio proklinjući: “Odlazi, odlazi, krvniče, ništarijo!"},{"v":8,"t":"Jahve je okrenuo na tebe svu krv Šaulova doma, kojemu si ti oduzeo kraljevstvo. Ujedno je Jahve predao kraljevstvo u ruke tvome sinu Abšalomu. Evo, sad si zapao u nevolju jer si krvnik.”"},{"v":9,"t":"Tada Sarvijin sin Abišaj zapita kralja: “Zar da ovaj uginuli pas proklinje moga gospodara kralja? Dopusti da odem prijeko i da mu skinem glavu!”"},{"v":10,"t":"Ali kralj odgovori: “Što hoćete od mene, Sarvijini sinovi? Ako on proklinje te ako mu je Jahve zapovjedio: 'Proklinji Davida!' - tko ga smije pitati: 'Zašto činiš tako?'”"},{"v":11,"t":"Nato David reče Abišaju i svim svojim dvoranima: “Eto, moj sin koji je izašao od moga tijela radi mi o glavi, a kamoli neće sada ovaj Benjaminovac! Pustite ga neka proklinje ako mu je Jahve to zapovjedio."},{"v":12,"t":"Možda će Jahve pogledati na moju nevolju te mi vratiti dobro za njegovu današnju psovku.”"},{"v":13,"t":"Zatim David sa svojim ljudima nastavi put, a Šimej iđaše gorskom stranom usporedo s njim, neprestano psujući, bacajući kamenje i dižući prašinu."},{"v":14,"t":"Kralj i sav narod koji ga je pratio stigoše umorni i ondje odahnuše."},{"v":15,"t":"Abšalom je međutim sa svim narodom izraelskim ušao u Jeruzalem; i Ahitofel bijaše s njim."},{"v":16,"t":"A kad je Hušaj Arčanin, Davidov prijatelj, došao k Abšalomu, reče Hušaj Abšalomu: “Živio kralj! Živio kralj!”"},{"v":17,"t":"A Abšalom upita Hušaja: “Je li to tvoja vjernost prema tvome prijatelju? Zašto nisi otišao sa svojim prijateljem?”"},{"v":18,"t":"A Hušaj odgovori Abšalomu: “Ne, nego koga je izabrao Jahve i ovaj narod i svi Izraelci, njegov ću biti i s njim ću ostati."},{"v":19,"t":"A drugo: kome ću služiti? Zar ne njegovu sinu? Kako sam služio tvojemu ocu, tako ću služiti tebi.”"},{"v":20,"t":"Potom se Abšalom obrati Ahitofelu: “Savjetuj sada: što da činimo?”"},{"v":21,"t":"Ahitofel odgovori Abšalomu: “Uđi k inočama svoga oca, koje je ostavio da čuvaju palaču: tada će sav Izrael čuti da si u zavadi sa svojim ocem, pa će se ohrabriti svi oni koji su pristali uz tebe.”"},{"v":22,"t":"Tada razapeše za Abšaloma šator na krovu i Abšalom uđe k inočama svoga oca na oči svemu Izraelu."},{"v":23,"t":"A savjet što bi ga dao Ahitofel u ono vrijeme vrijedio je kao odgovor Božji; toliko je vrijedio svaki Ahitofelov savjet i kod Davida i kod Abšaloma."}]},"17":{"hr":[{"v":1,"t":"Nato Ahitofel reče Abšalomu: “Dopusti da izaberem dvanaest tisuća ljudi pa da se dignem i pođem u potjeru za Davidom još noćas."},{"v":2,"t":"Navalit ću na njega kad bude umoran i bez snage; plašit ću ga i razbježat će se sav narod koji je s njim. Onda ću ubiti samoga kralja."},{"v":3,"t":"A sav ću narod dovesti natrag k tebi, kao što se mlada vraća svome mužu: ti radiš o glavi samo jednome čovjeku, a sav će narod onda biti miran.”"},{"v":4,"t":"Svidje se to Abšalomu i svim starješinama Izraelovim."},{"v":5,"t":"Ali Abšalom reče: “Pozovimo još Hušaja Arčanina da čujemo što će nam on kazati!”"},{"v":6,"t":"Kad je Hušaj došao k Abšalomu, reče mu Abšalom: “Ahitofel je svjetovao ovako. Hoćemo li učiniti kako je on predložio? Ako ne, govori ti!”"},{"v":7,"t":"A Hušaj odgovori Abšalomu: “Ovaj put savjet Ahitofelov nije dobar.”"},{"v":8,"t":"I nastavi Hušaj: “Ti znaš da su tvoj otac i njegovi ljudi junaci i da su ljuti kao medvjedica kojoj su oteli njezine medvjediće. Tvoj je otac ratnik, neće on dopustiti da narod počiva preko noći."},{"v":9,"t":"On se sada krije u kakvoj jami ili na kakvu drugom mjestu. Pa ako odmah u početku koji od naših padne, proširit će se glas o porazu u vojsci koja je pristala uz Abšaloma."},{"v":10,"t":"Tada će i najhrabriji, u koga je srce kao u lava, izgubiti srčanost. Jer sav Izrael zna da je tvoj otac junak i da su hrabri oni koji ga prate."},{"v":11,"t":"Zato ja svjetujem ovo: neka se sav Izrael, od Dana do Beer Šebe, okupi oko tebe, da ga bude kao pijeska na obali morskoj, a ti sam da stupaš u njihovoj sredini."},{"v":12,"t":"Tada ćemo navaliti na njega gdje se god bude nalazio, oborit ćemo se na nj kao što rosa pada na zemlju i nećemo ostaviti živa ni njega niti ikojega od njegovih ljudi."},{"v":13,"t":"Ako li se povuče u koji grad, sav će izraelski narod donijeti užeta pod onaj grad pa ćemo ga povlačiti do potoka, sve dok više ni kamenčića ne bude od njega.”"},{"v":14,"t":"Tada Abšalom i svi Izraelci rekoše: “Bolji je savjet Hušaja Arčanina nego savjet Ahitofelov.” Jer Jahve bijaše odlučio da se osujeti izvrsna Ahitofelova osnova, kako bi navukao nesreću na Abšaloma."},{"v":15,"t":"Potom Hušaj javi svećenicima Sadoku i Ebjataru: “Ahitofel je tako i tako savjetovao Abšaloma i starješine izraelske, a ja sam savjetovao tako i tako."},{"v":16,"t":"Zato sad brzo javite to Davidu i poručite mu: 'Nemoj noćas noćiti na ravnicama pustinje, nego brzo prijeđi na drugu stranu da ne bude uništen kralj i sva vojska koja je s njim.'”"},{"v":17,"t":"Jonatan i Ahimaas zadržavali se kod Rogelskog izvora; jedna je sluškinja dolazila i donosila im vijesti, a oni su odlazili da to jave kralju Davidu, jer se nisu smjeli odati ulazeći u grad."},{"v":18,"t":"Ali ih opazi neki momak te javi Abšalomu. Nato obojica žurno odoše i dođoše u kuću nekoga čovjeka u Bahurimu. U njegovu dvorištu bijaše studenac i oni se spustiše u nj."},{"v":19,"t":"A žena uze i razastrije pokrivač preko otvora studencu i posu po njem stučenoga zrnja, tako da se ništa nije moglo opaziti."},{"v":20,"t":"Abšalomove sluge dođoše k toj ženi u kuću i upitaše: “Gdje su Ahimaas i Jonatan?” A žena im odgovori: “Otišli su dalje prema vodi.” Potom su ih još tražili, ali ih ne nađoše pa se vratiše u Jeruzalem."},{"v":21,"t":"A kad su oni otišli, ona dvojica iziđoše iz studenca i odoše da donesu vijesti kralju Davidu. I rekoše mu: “Ustajte i prijeđite brže preko vode, jer je tako i tako savjetovao protiv vas Ahitofel.”"},{"v":22,"t":"Tada se David i sav narod što bijaše s njim diže i prijeđe preko Jordana; u zoru nije više bilo nijednoga koji nije prešao preko Jordana."},{"v":23,"t":"Kad je Ahitofel vidio da se nije izvršio njegov savjet, osamari svoga magarca, krenu na put i ode svojoj kući u svoj grad. Ondje se pobrinu za svoju kuću, zatim se objesi i umrije. Pokopaše ga u grobu njegova oca."},{"v":24,"t":"David je već bio došao u Mahanajim kad je Abšalom prešao preko Jordana sa svim Izraelcima koji bijahu s njim."},{"v":25,"t":"Abšalom bijaše postavio Amasu za zapovjednika nad vojskom namjesto Joaba. A Amasa je bio sin nekoga čovjeka po imenu Jitre, Jišmaelovca, koji je ušao k Abigajili, kćeri Jišajevoj i sestri Sarvije, Joabove majke."},{"v":26,"t":"Izrael i Abšalom udariše tabor u zemlji gileadskoj."},{"v":27,"t":"Kad je David došao u Mahanajim, tada Šobi, sin Nahašev iz Rabe Amonske, pa Makir, sin Amielov iz Lo Debara, i Barzilaj, Gileađanin iz Rogelima,"},{"v":28,"t":"donesoše postelja, pokrivača, čaša i zemljanog suđa, uz to pšenice, ječma, brašna, pržena žita, boba, leće,"},{"v":29,"t":"meda, kiseloga mlijeka i sira kravljeg i ovčjeg i ponudiše Davida i narod što bijaše s njim da jedu. Jer mišljahu: “Ljudi su u pustinji trpjeli glad, umor i žeđu.”"}]},"18":{"hr":[{"v":1,"t":"Potom David pobroji narod što bijaše s njim i postavi nad njima tisućnike i stotnike."},{"v":2,"t":"Zatim podijeli vojsku na tri skupine: jednu trećinu predade Joabu, drugu trećinu Abišaju, sinu Sarvijinu, bratu Joabovu, a treću trećinu Itaju iz Gata. Tada David reče narodu: “I ja ću s vama u rat.”"},{"v":3,"t":"Ali se narod usprotivi: “Ne smiješ ti ići. Jer ako mi i pobjegnemo, neće nitko na to obraćati pažnju, ili ako nas i pola izgine, neće se na to obraćati pažnja; ali ti sam vrijediš kao nas deset tisuća. Osim toga, bolje je da budeš pripravan da nam iz grada pomogneš.”"},{"v":4,"t":"A kralj im odgovori: “Učinit ću sve što vam se čini dobro.” I kralj stade kod vrata dok je vojska izlazila po stotinama i tisućama."},{"v":5,"t":"A Joabu, Abišaju i Itaju dade zapovijed: “Čuvajte mi mladića Abšaloma!” I sav je narod čuo da je kralj tako zapovjedio svim vojvodama za Abšaloma."},{"v":6,"t":"Tako vojska iziđe za boj spremna pred Izraela i bitka se zametnu u Efrajimovoj šumi."},{"v":7,"t":"Izraelsku vojsku potukoše Davidovi ljudi; i velik poraz bijaše u onaj dan: dvadeset tisuća mrtvih."},{"v":8,"t":"Boj se proširio po svemu onom kraju i više je ljudi onoga dana progutala šuma nego mač."},{"v":9,"t":"Abšalom slučajno zapade u ruke Davidovim ljudima. Abšalom je jahao na mazgi, a mazga naiđe pod grane velika hrasta, tako te je Abšalomu glava zapela o grane i on osta viseći između neba i zemlje, dok je mazga ispod njega otišla dalje."},{"v":10,"t":"Vidje to neki čovjek i javi Joabu govoreći: “Upravo sam vidio Abšaloma gdje visi o jednom hrastu.”"},{"v":11,"t":"A Joab odvrati čovjeku koji mu je to javio: “Kad si ga vidio, zašto ga na mjestu nisi sastavio sa zemljom? Moja bi onda bila dužnost da ti dam deset srebrnih šekela i jedan pojas!”"},{"v":12,"t":"Ali čovjek odgovori Joabu: “I kad bi mi na dlan izbrojio tisuću srebrnih šekela, ne bih digao ruku na kraljeva sina! Čuli smo na svoje uši kako je kralj zapovjedio tebi, Abišaju i Itaju govoreći: 'Čuvajte mi mladića Abšaloma!'"},{"v":13,"t":"Da sam podmuklo napao na njega izlažući opasnosti svoj život - jer kralju ništa ne ostaje skriveno - onda bi se ti držao po strani.”"},{"v":14,"t":"A Joab odvrati: “Neću ja ovdje dangubiti s tobom!” I uze tri sulice u ruke i zabode ih u srce Abšalomu, koji je bio još živ viseći o hrastu."},{"v":15,"t":"Nato priđe deset momaka, štitonoša Joabovih, i dotukoše Abšaloma i usmrtiše."},{"v":16,"t":"Tada Joab zapovjedi da zatrube u rog, i vojska prestade progoniti Izraela jer je Joab zaustavio vojsku."},{"v":17,"t":"Potom uzeše Abšaloma, baciše ga u duboku jamu usred šume i navaljaše na nj veliku gomilu kamenja. Izraelci pak pobjegoše svaki svome šatoru."},{"v":18,"t":"Abšalom bijaše još za života postavio sebi spomenik u Kraljevoj dolini jer mišljaše: “Nemam sina koji bi sačuvao spomen mome imenu.” I nazvao je taj spomenik po svome imenu te se još i danas zove “Abšalomov spomenik”."},{"v":19,"t":"Ahimaas, Sadokov sin, reče Joabu: “Idem javiti kralju veselu vijest da mu je Jahve pribavio pravdu izbavivši ga iz ruku njegovih neprijatelja.”"},{"v":20,"t":"Ali mu Joab reče: “Ne možeš danas biti glasnik vesele vijesti, nego ćeš to biti koji drugi dan; danas ne možeš javiti dobru vijest jer je poginuo kraljev sin.”"},{"v":21,"t":"Zatim Joab zapovjedi Etiopljaninu: “Idi javi kralju što si vidio!” Etiopljanin se pokloni Joabu i otrča."},{"v":22,"t":"A Sadokov sim Ahimaas opet zamoli Joaba: “Dogodilo se što mu drago, dopusti da otrčim i ja za Etiopljaninom.” A Joab upita: “Zašto bi trčao, sine moj, kad ti ta vesela vijest neće pribaviti nagrade?”"},{"v":23,"t":"A on ponovi: “Dogodilo se što mu drago, trčat ću!” A Joab mu odvrati: “Trči!” I Ahimaas otrča putem kroz ravnicu i preteče Etiopljanina."},{"v":24,"t":"David je upravo sjedio među dvojim gradskim vratima, a stražar se bio uspeo na krov iznad vrata. Podigavši oči, stražar ugleda čovjeka kako trči sam."},{"v":25,"t":"Stražar povika i javi kralju, a kralj mu reče: “Ako je sam, nosi dobar glas na ustima.” Čovjek je dolazio sve bliže."},{"v":26,"t":"Uto stražar ugleda drugoga čovjeka gdje trči. I povika stražar koji je bio nad vratima: “Evo još jednoga čovjeka koji trči sam!” A kralj odvrati: “I taj nosi dobar glas.”"},{"v":27,"t":"Stražar nastavi: “Prepoznajem trk prvoga čovjeka: trči kao Sadokov sin Ahimaas.” A kralj odvrati: “To je dobar čovjek, dolazi s dobrim glasom.”"},{"v":28,"t":"Ahimaas se približi kralju i pozdravi ga: “Zdravo!” Baci se licem na zemlju pred kraljem i nastavi: “Blagoslovljen Jahve, tvoj Bog, koji je napustio ljude što su digli ruku na moga gospodara i kralja!”"},{"v":29,"t":"A kralj upita: “Je li spašen mladić Abšalom?” A Ahimaas odgovori: “Vidio sam veliku vrevu kad je kraljev sluga Joab slao tvoga slugu, ali ne znam što je bilo.”"},{"v":30,"t":"Kralj mu reče: “Odstupi i stani tamo!” On odstupi i stade."},{"v":31,"t":"Uto stiže Etiopljanin i progovori: “Neka moj gospodar kralj primi veselu vijest. Jahve ti je danas pribavio pravdu izbavivši te iz ruku svih onih koji su ustali na tebe.”"},{"v":32,"t":"A kralj upita Etiopljanina: “Je li spašen mladić Abšalom?” A Etiopljanin odgovori: “Neka neprijatelji moga gospodara i kralja i svi koji se dižu na tebe u zloj namjeri - prođu kao taj mladić!”"}]},"19":{"hr":[{"v":1,"t":"Kralj zadrhta, pope se u gornju odaju nad vratima i zaplaka; jecajući govoraše ovako: “Sine Abšalome, sine moj! Sine moj Abšalome! Oh, da sam ja umro mjesto tebe! Abšalome, sine moj, sine moj!”"},{"v":2,"t":"I javiše Joabu: “Eno kralj plače i tuguje za Abšalomom.”"},{"v":3,"t":"Tako se pobjeda u onaj dan pretvorila u žalost za svu vojsku, jer je vojska čula u onaj dan da kralj tuguje za svojim sinom."},{"v":4,"t":"I toga se dana vojskom kradom vrati u grad, kao što se kradom šulja vojska koja se osramotila bježeći iz boja."},{"v":5,"t":"A kralj je pokrio svoje lice i vapio iza glasa: “Sine moj Abšalome! Abšalome, sine moj! Sine moj!”"},{"v":6,"t":"Tada Joab dođe kralju u kuću i reče mu: “Postiđuješ danas lice svih svojih slugu koji su danas spasili život tebi, život tvojim sinovima i tvojim kćerima, život tvojim ženama i život inočama tvojim,"},{"v":7,"t":"jer iskazuješ ljubav onima koji te mrze, a mržnju onima koji te ljube. Danas si pokazao da ti ništa nije ni do vojvoda ni do vojnika, jer vidim sada da bi ti sasvim pravo bilo kad bi Abšalom bio živ, a mi svi da smo danas poginuli."},{"v":8,"t":"Zato sada ustani, iziđi i prijazno progovori svojim vojnicima; jer, kunem ti se Jahvom, ako ne iziđeš, nijedan čovjek neće ostati noćas s tobom, i to će ti biti veća nesreća od svih koje su te snašle od tvoje mladosti pa do sada.”"},{"v":9,"t":"Kralj ustade i sjede na vrata. Javiše to svemu narodu govoreći: “Eno kralj sjedi na vratima.” I sav narod dođe pred kralja. A Izraelci bijahu pobjegli svaki u svoj šator."},{"v":10,"t":"I sav se narod po svim Izraelovim plemenima prepirao govoreći: “Kralj nas je izbavio iz ruku naših neprijatelja, on nas je izbavio iz ruku filistejskih, a sada je morao pobjeći iz zemlje ispred Abšaloma."},{"v":11,"t":"A Abšalom koga smo pomazali za kralja poginuo je u boju. Zašto se, dakle, kolebate dovesti kralja natrag?”"},{"v":12,"t":"Te riječi svega Izraela dopru do kralja u njegovu kuću. Zato kralj David poruči svećenicima Sadoku i Ebjataru: “Recite starješinama judejskim ovako: 'Zašto da vi budete posljednji koji će kralja dovesti u njegovu kuću?"},{"v":13,"t":"Vi ste moja braća, vi ste od moga mesa i od mojih kosti. Zašto biste, dakle, bili posljednji koji će dovesti kralja natrag?'"},{"v":14,"t":"Recite i Amasi: 'Nisi li ti od mojih kosti i od moga mesa? Neka mi Bog učini zlo i neka mi doda drugo ako mi ne budeš zauvijek vojvoda nad mojom vojskom namjesto Joaba!'”"},{"v":15,"t":"Tada se složiše svi ljudi Judina roda kao jedan čovjek i poručiše kralju: “Vrati se sa svim svojim ljudima!”"},{"v":16,"t":"I tako se kralj vrati i dođe do Jordana, a Judejci bijahu stigli do Gilgala dolazeći u susret kralju da prate kralja na prijelazu preko Jordana."},{"v":17,"t":"Tada je pohitio i Šimej, sin Gerin, Benjaminovac iz Bahurima, i sišao s Judejcima u susret kralju Davidu."},{"v":18,"t":"Imao je sa sobom tisuću ljudi od Benjaminova plemena. I Siba, sluga Šaulova doma, sa petnaest svojih sinova i dvadeset svojih slugu, dođe do Jordana pred kralja."},{"v":19,"t":"Dovezli su splav da prevezu kraljevu čeljad i da učine sve što bi mu bilo drago. A Gerin sin Šimej baci se pred noge kralju kad je kralj htio prijeći preko Jordana;"},{"v":20,"t":"i reče kralju: “Neka mi moj gospodar ne upiše u grijeh! Ne opominji se zla što ti ga je učinio tvoj sluga u onaj dan kad je moj gospodar i kralj izlazio iz Jeruzalema. Neka to kralj ne uzima k srcu!"},{"v":21,"t":"Tvoj sluga uviđa da je sagriješio; zato sam, evo, došao danas prvi iz svega Josipova doma da siđem u susret svome gospodaru i kralju.”"},{"v":22,"t":"Ali Sarvijin sin Abišaj progovori i reče: “Zar Šimej ne zaslužuje smrt što je proklinjao pomazanika Jahvina?”"},{"v":23,"t":"A David odgovori: “Što ja imam s vama, Sarvijini sinovi, te me danas uvodite u napast? Zar bi danas mogao tko biti pogubljen u Izraelu? TÓa sada znam da sam danas opet kralj nad Izraelom.”"},{"v":24,"t":"Tada kralj reče Šimeju: “Nećeš poginuti!” I kralj mu se zakle."},{"v":25,"t":"I Šaulov sin Meribaal sišao je u susret kralju. On nije njegovao ni svojih nogu ni svojih ruku, nije uređivao svoje brade, nije prao svojih haljina od onoga dana kad je otišao kralj pa sve do dana kad se opet vratio u miru."},{"v":26,"t":"Kad je iz Jeruzalema došao u susret kralju, upita ga kralj: “Zašto nisi pošao sa mnom, Meribaale?”"},{"v":27,"t":"A on odgovori: “Kralju gospodaru! Moj me sluga prevario. Tvoj mu je sluga rekao: 'Osamari mi magaricu da je uzjašem i pođem s kraljem!' Jer tvoj je sluga hrom."},{"v":28,"t":"On je oklevetao tvoga slugu pred mojim gospodarom i kraljem. Ali moj je gospodar i kralj kao Božji anđeo: zato čini što je dobro u tvojim očima."},{"v":29,"t":"Jer sav moj očinski dom nije bio drugo zaslužio nego smrt od moga gospodara kralja, a ti si ipak primio svoga slugu među one koji jedu za tvojim stolom. Pa kako još imam pravo tužiti se kralju?”"},{"v":30,"t":"A kralj mu odgovori: “Čemu da još duljiš svoj govor? Određujem: ti i Siba podijelite njive!”"},{"v":31,"t":"Meribaal reče kralju: “Neka uzme i sve, kad se moj gospodar kralj sretno vratio u svoj dom!”"},{"v":32,"t":"I Barzilaj Gileađanin dođe iz Rogelima i nastavi s kraljem da ga isprati preko Jordana."},{"v":33,"t":"Barzilaj bijaše vrlo star, bilo mu je osamdeset godina. Pribavljao je kralju opskrbu dok je boravio u Mahanajimu jer bijaše vrlo imućan čovjek."},{"v":34,"t":"Kralj reče Barzilaju: “Pođi sa mnom, ja ću te u tvojim starim danima uzdržavati kod sebe u Jeruzalemu.”"},{"v":35,"t":"A Barzilaj odgovori kralju: “A koliko mi još godina života ostaje da idem s kraljem u Jeruzalem?"},{"v":36,"t":"Sada mi je osamdeset godina; mogu li još razlikovati što je dobro a što zlo? Može li tvojem sluzi još goditi što jede i pije? Mogu li još slušati glas pjevača i pjevačica? Zašto bi tvoj sluga bio još na teret mome gospodaru kralju?"},{"v":37,"t":"Tvoj će sluga još samo prijeći preko Jordana s kraljem, ali zašto bi mi kralj dao takvu nagradu?"},{"v":38,"t":"Dopusti svome sluzi da se vrati, da umrem u svom gradu kod groba svoga oca i svoje majke. Ali evo tvoga sluge Kimhama, neka ide dalje s mojim gospodarom kraljem, pa njemu učini što je dobro u tvojim očima!”"},{"v":39,"t":"Kralj odgovori: “Neka onda Kimham ide sa mnom dalje, a ja ću mu učiniti što bude tebi drago i što god me zamoliš sve ću mu učiniti za tebe.”"},{"v":40,"t":"Kad je sav narod prešao preko Jordana, prijeđe i kralj, poljubi Barzilaja i blagoslovi ga, potom se ovaj vrati u svoje mjesto."},{"v":41,"t":"Kralj nastavi put u Gilgal, a Kimham iđaše s njim. Kralja je pratio sav narod Judin i polovina naroda Izraelova."},{"v":42,"t":"Uto svi Izraelci dođu pred kralja i upitaju ga: “Zašto te naša braća Judejci ukradoše i zašto prevedoše preko Jordana našega kralja i njegov dom i sve Davidove ljude s njim?”"},{"v":43,"t":"A Juda odgovori Izraelu: “Kralj je meni rod. Zašto si se ražestio zbog toga? Jesam li jeo na kraljev račun? Ili sam si što prigrabio?”"},{"v":44,"t":"Tada Izrael odgovori Judi ovako: “Ja imam deset udjela na kralja i prema tebi ja sam prvorođenac. Zašto si me, dakle, prezreo? Nije li moja riječ bila prva kad je trebalo natrag dovesti moga kralja?” Ali govor Judin bijaše tvrđi od govora Izraelova."}]},"20":{"hr":[{"v":1,"t":"Ondje se slučajno našao opak čovjek po imenu Šeba, Bikrijev sin, Benjaminovac. On zatrubi u rog i viknu: “Mi nemamo udjela na Davidu ni baštine na Jišajevu sinu! Svaki svome šatoru, Izraele!”"},{"v":2,"t":"Tako svi Izraelci ostaviše Davida i pođoše za Bikrijevim sinom Šebom; a Judejci prionuše uza svoga kralja i otpratiše ga od Jordana do Jeruzalema."},{"v":3,"t":"Kad se David vratio u svoju palaču u Jeruzalem, uze deset inoča koje je bio ostavio da čuvaju palaču i stavi ih da budu čuvane. Brinuo im se za uzdržavanje, ali nije više išao k njima. Tako su one živjele zatvorene do svoje smrti, kao udovice živoga muža."},{"v":4,"t":"Potom kralj zapovjedi Amasi: “Sazovi mi Judejce do tri dana, a i ti da budeš ovdje!”"},{"v":5,"t":"Amasa ode da sazove Judejce, ali se zadrža preko vremena koje mu bijaše odredio kralj."},{"v":6,"t":"Tada David reče Abišaju: “Sad će nam Bikrijev sin Šeba biti opasniji nego Abšalom. Zato uzmi ljude svoga gospodara i pođi za njim u potjeru da se ne domogne tvrdih gradova i ne izmakne nam iz očiju!”"},{"v":7,"t":"Za Abišajem krenu na put Joab, Kerećani, Pelećani i svi junaci; oni iziđu iz Jeruzalema u potjeru za Bikrijevim sinom Šebom."},{"v":8,"t":"Kad su bili kod velikoga kamena što je kod Gibeona, dođe Amasa prema njima. Joab imaše na sebi ratnu haljinu, a preko nje imaše pripasan mač uz bedro, u koricama; ali mu se mač iskliznu i pade."},{"v":9,"t":"Joab pozdravi Amasu: “Jesi li mi dobro, brate?” I desnom rukom uhvati za bradu Amasu da ga poljubi."},{"v":10,"t":"Amasa se nije obazirao na mač koji bijaše Joabu u ruci, i on ga udari njim u trbuh i prosu mu utrobu na zemlju. Nije morao ponoviti udarac i Amasa umrije. Joab sa svojim bratom Abišajem nastavi potjeru za Bikrijevim sinom Šebom."},{"v":11,"t":"Jedan od Joabovih momaka osta na straži kod Amase i tu je vikao: “Kome je mio Joab i tko je za Davida neka slijedi Joaba!”"},{"v":12,"t":"A Amasa ležao u krvi nasred puta. Videći onaj čovjek gdje se ustavlja sav narod, odvuče Amasu s puta u polje i baci preko njega kabanicu jer je vidio gdje se zaustavlja svatko tko naiđe blizu njega."},{"v":13,"t":"Kad je Amasa bio uklonjen s puta, svi ljudi pođoše za Joabom da gone Bikrijeva sina Šebu."},{"v":14,"t":"Šeba je prošao kroza sva izraelska plemena sve do Abel Bet Maake i svi Bikrani s njim. Skupiše se oni i pođoše za njim."},{"v":15,"t":"Joab dođe i opsjede ga u Abel Bet Maaki. Dade nasuti nasip oko grada. Sva vojska koja bijaše s Joabom navali potkopavati zid da ga obori."},{"v":16,"t":"Tada se jedna mudra žena uspe na zid i povika iz grada: “Čujte! Čujte! Recite Joabu: 'Priđi ovamo, da govorim s tobom!'”"},{"v":17,"t":"Kad je prišao, upita žena: “Jesi li ti Joab?” On odgovori: “Jesam.” A ona će: “Poslušaj riječ sluškinje svoje!” On odgovori: “Slušam.”"},{"v":18,"t":"Žena nastavi: “Nekoć se govorilo ovako: 'Treba pitati u Abelu i u Danu"},{"v":19,"t":"je li svršeno s onim što su utvrdili vjernici u Izraelu.' Ti bi htio uništiti jedan grad, i to jedan od matičnih gradova u Izraelu. Zašto zatireš baštinu Jahvinu?”"},{"v":20,"t":"Joab odgovori ovako: “Daleko, daleko bilo to od mene! Ne želim ni zatirati ni razarati."},{"v":21,"t":"Ne radi se o tome, nego je jedan čovjek iz Efrajimove gore, po imenu Šeba, Bikrijev sin, podigao ruku na kralja, na Davida. Predajte samo njega, pa ću otići od grada!” Žena odgovori Joabu: “Dobro. Odmah će ti njegovu glavu baciti preko zida!”"},{"v":22,"t":"Žena se vrati u grad i progovori svemu narodu kako joj je govorila njezina mudrost. I odsjekoše glavu Bikrijevu sinu Šebi i baciše je Joabu. A on zapovjedi da zatrube u rog te se raziđoše od grada, svaki u svoj kraj. A Joab se vrati kralju u Jeruzalem."},{"v":23,"t":"Joab je bio zapovjednik nad svom vojskom. Jojadin sin Benaja bio je zapovjednik nad Kerećanima i Pelećanima."},{"v":24,"t":"Adoram je bio nadglednik nad radovima. Ahiludov sin Jošafat bio je pečatnik."},{"v":25,"t":"Seraja je bio državni pisar. Sadok i Ebjatar bijahu svećenici."},{"v":26,"t":"Uz to je Jairanin Ira bio zamjenik Davidov."}]},"21":{"hr":[{"v":1,"t":"U dane Davidove vladaše jednom glad tri godine uzastopce. David se obrati Jahvi, a Jahve mu odgovori: “Na Šaulu i njegovu domu leži krvna krivnja jer je pogubio Gibeonce.”"},{"v":2,"t":"Tada kralj sazva Gibeonce da ih pita. Ti Gibeonci nisu pripadali Izraelcima, nego su bili ostatak Amorejaca, kojima se Izraelci bijahu zakleli zakletvom, ali je Šaul tražio da ih uništi u svojoj revnosti za Izraelce i Judejce."},{"v":3,"t":"David, dakle, upita Gibeonce: “Što da vam učinim i čime da vam dadem zadovoljštinu da biste blagoslovili baštinu Jahvinu?”"},{"v":4,"t":"Gibeonci odgovoriše: “Ne tražimo mi ni srebra ni zlata od Šaula i njegova doma, niti nam je stalo da se pogubi koji čovjek u Izraelu.” David će im nato: “Što reknete učinit ću za vas.”"},{"v":5,"t":"A oni odgovoriše kralju: “Čovjek koji nas je zatirao i koji je smišljao da nas uništi, da nas ne bude nigdje u svemu izraelskom području,"},{"v":6,"t":"od njegovih potomaka neka nam se preda sedam ljudi da ih objesimo pred Jahvom u Gibeonu na gori Jahvinoj.” Kralj odvrati: “Dat ću vam ih.”"},{"v":7,"t":"Kralj poštedje Meribaala, sina Šaulova sina Jonatana, zbog zakletve pred Jahvom koja ih je vezala, Davida i Jonatana, sina Šaulova."},{"v":8,"t":"Tako kralj uze oba sina Rispe, Ajine kćeri, koje je rodila Šaulu, Armonija i Meribaala, i svih pet sinova Merabe, Šaulove kćeri, koje je rodila Adrielu, sinu Barzilajevu, iz Mehole."},{"v":9,"t":"Njih dade u ruke Gibeoncima, a oni ih objesiše na gori pred Jahvom. Tako sva sedmorica poginuše zajedno, pogubljeni prvih dana žetve, na početku ječmene žetve."},{"v":10,"t":"Rispa, Ajina kći, uze kostrijet i prostrije je za sebe na stijeni od početka ječmene žetve sve dok nije kiša s neba pala na mrtva tijela, i tako nije dala nebeskim pticama da se spuštaju na njih danju ni poljskim zvijerima noću."},{"v":11,"t":"Kad su Davidu javili što je učinila Ajina kći Rispa, Šaulova inoča,"},{"v":12,"t":"ode David i uze Šaulove kosti i kosti njegova sina Jonatana od stanovnika Jabeša Gileadskog, koji ih bijahu potajno odnijeli s trga u Bet Šanu, gdje su ih objesili Filistejci u onaj dan kad su Filistejci porazili Šaula na Gilboi."},{"v":13,"t":"David prenese odande Šaulove kosti i kosti njegova sina Jonatana pa ih združi s kostima pogubljenih."},{"v":14,"t":"I ukopaše Šaulove kosti i kosti njegova sina Jonatana s kostima pogubljenih u zemlji Benjaminovoj, u Seli, u grobu Šaulova oca Kiša. Pošto izvršiše sve što je kralj zapovjedio, Bog se smilova zemlji."},{"v":15,"t":"Jednom opet nasta rat između Filistejaca i Izraelaca. David ode u boj sa svojim ljudima te su se borili s Filistejcima tako da se David umorio."},{"v":16,"t":"Išibenob, jedan od Rafinih potomaka, čije je koplje bilo teško tri stotine mjedenih šekela i koji o pripasu imaše nov mač, hvastao se tada da će ubiti Davida."},{"v":17,"t":"Ali Davidu priskoči u pomoć Sarvijin sin Abišaj; udari on Filistejca te ga ubi. Tada se Davidovi ljudi zakleše rekavši Davidu: “Nećeš više ići s nama u boj, da ne ugasiš svjetiljke Izraelove!”"},{"v":18,"t":"Poslije toga opet izbi rat s Filistejcima u Gobu; tada je Hušanin Sibkaj pogubio Sipaja, jednoga od Rafinih potomaka."},{"v":19,"t":"Uz to nasta rat s Filistejcima u Gobu; tada je Jairov sin Elhanan iz Betlehema pogubio Golijata Gitejca, koji je imao kopljaču kao tkalačko vratilo."},{"v":20,"t":"Potom opet izbi rat u Gatu, gdje je bio neki čovjek visoka rasta: imaše taj na svakoj ruci i nozi po šest prstiju, dakle dvadeset i četiri; i on bijaše potomak Rafin."},{"v":21,"t":"Kad je počeo ružiti Izraela, ubi ga Jonatan, sin Davidova brata Šimeja."},{"v":22,"t":"Ta četvorica bijahu potomci istoga Rafe iz Gata, a poginuše od ruke Davidove i od ruku njegovih slugu."}]},"22":{"hr":[{"v":1,"t":"David upravi Jahvi riječi ove pjesme u dan kad ga je Jahve izbavio iz ruku svih njegovih neprijatelja i iz ruke Šaulove."},{"v":2,"t":"Pjevao je: “Jahve, hridino moja, utvrdo moja, spase moj;"},{"v":3,"t":"Bože moj, pećino moja kojoj se utječem, štite moj, spasenje moje, tvrđavo moja! Ti me izbavljaš od nasilja."},{"v":4,"t":"Zazvat ću Jahvu hvale predostojna i od dušmana bit ću izbavljen."},{"v":5,"t":"Valovi smrti okružiše mene, prestraviše me bujice pogubne,"},{"v":6,"t":"Užad Podzemlja sputiše me, smrtonosne zamke padoše na me:"},{"v":7,"t":"u nevolji zazvah Jahvu i Bogu svome zavapih. Iz svog Doma zov mi začu, i vapaj moj mu do ušiju doprije."},{"v":8,"t":"I zemlja se potrese i uzdrhta, uzdrmaše se temelji nebesa, pokrenuše se, jer On gnjevom planu."},{"v":9,"t":"Iz nosnica mu dim se diže, iz usta mu oganj liznu, ugljevlje živo od njega plamsa."},{"v":10,"t":"On nagnu nebesa i siđe, pod nogama oblaci mu mračni."},{"v":11,"t":"Na keruba stade i poletje; na krilima vjetra zaplovi."},{"v":12,"t":"Ogrnu se mrakom kao koprenom, prekri se tamnim vodama i oblacima tmastim,"},{"v":13,"t":"od bljeska pred licem njegovim užga se ugljevlje plameno."},{"v":14,"t":"Jahve s neba zagrmje, Svevišnjega glas se ori."},{"v":15,"t":"Odape strijele i dušmane rasu, izbaci munje i na zemlju ih obori."},{"v":16,"t":"Morska dna se pokazaše, i temelji svijeta postaše goli od strašne prijetnje Jahvine, od olujna daha gnjeva njegova."},{"v":17,"t":"On pruži s neba ruku i mene prihvati, iz silnih voda on me izbavi."},{"v":18,"t":"Od protivnika moćnog mene oslobodi, od dušmana mojih jačih od mene."},{"v":19,"t":"Navališe na me u dan zlosretni, ali me Jahve zaštiti,"},{"v":20,"t":"na polje prostrano izvede me, spasi me jer sam mu mio."},{"v":21,"t":"Po pravednosti mojoj Jahve mi uzvrati, po čistoći ruku mojih on me nagradi,"},{"v":22,"t":"jer čuvah putove Jahvine, od Boga se svoga ne udaljih."},{"v":23,"t":"Odredbe njegove sve su mi pred očima, zapovijedi njegove nisam odbacio,"},{"v":24,"t":"do srži odan njemu sam bio, čuvam se grijeha svakoga."},{"v":25,"t":"Jahve mi po pravdi mojoj vrati, čistoću ruku mojih vidje."},{"v":26,"t":"S prijateljem ti si prijatelj, poštenu poštenjem uzvraćaš."},{"v":27,"t":"S čovjekom čistim ti si čist, a lukavca izigravaš,"},{"v":28,"t":"jer narodu poniženu spasenje donosiš a ponižavaš oči ohole."},{"v":29,"t":"Jahve, ti moju svjetiljku užižeš, Bože, tminu moju obasjavaš:"},{"v":30,"t":"s tobom udaram na čete dušmanske, s Bogom svojim preskačem zidine."},{"v":31,"t":"Savršeni su puti Gospodnji, i riječ je Jahvina ognjem kušana. on je štit svima, samo on, koji se k njemu utječu."},{"v":32,"t":"Jer tko je Bog osim Jahve? Tko li je hridina osim Boga našega?"},{"v":33,"t":"Taj Bog me snagom opasuje, stere mi put besprijekoran."},{"v":34,"t":"Noge mi dade brze ko u košute i postavi me na visine sigurne,"},{"v":35,"t":"ruke mi za borbu uvježba i mišice da luk mjedeni napinju."},{"v":36,"t":"Daješ mi štit svoj koji spasava, tvoja me brižljivost uzvisi."},{"v":37,"t":"Pouzdanje daješ mom koraku, i noge mi više ne posrću."},{"v":38,"t":"Pognah svoje dušmane i dostigoh, i ne vratih se dok ih ne uništih."},{"v":39,"t":"Obaram ih, ne mogu se dići, padaju, pod nogama mi leže."},{"v":40,"t":"Ti me opasa snagom za borbu, a protivnike moje meni podloži."},{"v":41,"t":"Ti dušmane moje u bijeg natjera, i rasprših one koji su me mrzili."},{"v":42,"t":"Vapiju u pomoć, nikog da pomogne, vapiju Jahvi - ne odaziva se."},{"v":43,"t":"Smrvih ih kao prah na vjetru, zgazih ih ko blato na putu."},{"v":44,"t":"Ti me §izbavÄi od bune u mom narodu, postavi me glavarom pogana, puk koji ne poznavah služi mi."},{"v":45,"t":"Svaki moj šapat pokorno on sluša. Sinovi tuđinci meni laskaju,"},{"v":46,"t":"sinovi tuđinski gube srčanost izlaze dršćuć iz svojih utvrda."},{"v":47,"t":"Živio Jahve! Blagoslovljena hridina moja! Neka se uzvisi Bog, spasenje moje!"},{"v":48,"t":"Bog koji mi daje osvetu i narode meni pokorava."},{"v":49,"t":"Od dušmana me mojih izbavljaš i nad protivnike me moje izdižeš, ti mene od čovjeka silnika spasavaš."},{"v":50,"t":"Zato te slavim, Jahve, među pucima i psalam pjevam tvome Imenu:"},{"v":51,"t":"umnožio si pobjede kralju svojemu, pomazaniku svome milost si iskazao, Davidu i potomstvu njegovu navijeke.”"}]},"23":{"hr":[{"v":1,"t":"Ovo su posljednje Davidove riječi: “Riječ Davida, sina Jišajeva, riječ čovjeka koji je bio visoko uzdignut, pomazanika Boga Jakovljeva, pjevača pjesama Izraelovih:"},{"v":2,"t":"Jahvin duh govori po meni, njegova je riječ na mom jeziku."},{"v":3,"t":"Reče mi Jakovljev Bog, reče mi Izraelova hrid: Tko vlada ljudima pravedno, i tko vlada u strahu Božjemu,"},{"v":4,"t":"taj je kao jutarnja svjetlost kad ograne sunce, jutro bez oblaka, na kojem se svjetluca zemaljska trava poslije kiše."},{"v":5,"t":"Da, moja kuća stoji čvrsto pred Bogom: on je učinio vječan Savez sa mnom, u svemu dobro uređen i utvrđen. Da, on će dati da napreduje sve moje spasenje i svaka moja želja."},{"v":6,"t":"Belijalovi ljudi svi su kao trnje u pustinji, jer ih nitko ne hvata rukom."},{"v":7,"t":"Nitko ih se ne dotiče, osim gvožđem i kopljačom, i potpuno se spaljuju u ognju.”"},{"v":8,"t":"Ovo su imena Davidovih junaka: Išbaal, Hakmonac, prvak među trojicom; on je zavitlao svojim kopljem protiv osam stotina i pobio ih najedanput."},{"v":9,"t":"Za njim dolazi Eleazar, sin Dodonov, Ahoašanin, jedan od trojice junaka; on je bio s Davidom kod Pas Damina kad su se ondje skupili Filistejci za boj, a Izraelci se povukli pred njima."},{"v":10,"t":"Ali se on čvrsto držao i udarao Filistejce dok mu se ruka nije ukočila i ostala kao prirasla uz mač. Jahve je dao veliku pobjedu u onaj dan, pa se vojska vratila za Eleazarom, ali samo da pokupi plijen."},{"v":11,"t":"Za njim dolazi Šama, sin Elin, Hararac; kad su se Filistejci skupili u Lehiju, bijaše polje puno leće, a vojska je bila pobjegla ispred Filistejaca."},{"v":12,"t":"Tada je on stao usred polja i obranio ga i potukao Filistejce. Tako je Jahve dao veliku pobjedu."},{"v":13,"t":"Trojica između tridesetorice jednom su krenula na put i o početku žetve došla k Davidu u Adulamsku pećinu kad jedna filistejska četa bijaše utaborena u Refaimskoj dolini."},{"v":14,"t":"David je tada bio u svojoj kuli, a filistejska je posada bila tada u Betlehemu."},{"v":15,"t":"David uzdahnu: “O, kad bi me tko napojio vodom iz betlehemskoga studenca što je kod vrata?”"},{"v":16,"t":"Tada ta tri junaka prodriješe kroz filistejski tabor i, zahvativši vode iz betlehemskog studenca što je kod vrata, donesoše je i dadoše Davidu. Ali je David ne htjede piti, nego je proli kao ljevanicu Jahvi"},{"v":17,"t":"govoreći: “Ne dao mi Jahve da to učinim! Zar da pijem krv ovih ljudi? TÓa izlažući život pogibli, donijeli su vode!” I nije htio piti. To su, eto, učinila ta tri junaka."},{"v":18,"t":"Abišaj, Joabov brat a sin Sarvijin, bio je vojvoda nad tridesetoricom. On je zavitlao kopljem na tri stotine, pobio ih i proslavio se među tridesetoricom."},{"v":19,"t":"On se odlikovao među tridesetoricom i postao njihov glavar, ali nije dostigao trojice."},{"v":20,"t":"Jojadin sin Benaja, junak iz Kabseela, bogat junačkim djelima, ubio je dva sina Ariela iz Moaba; on je jednoga snježnog dana sišao i ubio lava usred jame."},{"v":21,"t":"Ubio je i nekog Egipćanina, čovjeka golema stasa. Egipćanin je imao koplje u ruci, a on izišao preda nj sa štapom: istrgavši Egipćaninu koplje iz ruke, ubi ga njegovim kopljem."},{"v":22,"t":"To je učinio Jojadin sin Benaja i proslavio se među tridesetoricom junaka."},{"v":23,"t":"Bio je najznamenitiji među tridesetoricom, ali one prve trojice nije dostigao; David ga postavi za zapovjednika svoje tjelesne straže."},{"v":24,"t":"Asahel, brat Joabov, bio je među tridesetoricom. Zatim: Elhanan, sin Dodonov, iz Betlehema;"},{"v":25,"t":"Šama iz Haroda; Elika iz Haroda;"},{"v":26,"t":"Heles iz Peleta; Ira, sin Ikešev, iz Tekoe;"},{"v":27,"t":"Abiezer iz Anatota; Sibekaj iz Huše;"},{"v":28,"t":"Salmon iz Ahoha; Mahraj iz Netofe;"},{"v":29,"t":"Heled, sin Baanin, iz Netofe; Itaj, sin Ribajev, iz Gibeje sinova Benjaminovih;"},{"v":30,"t":"Benaja iz Pireatona; Hidaj od Gaaških potoka;"},{"v":31,"t":"Abibaal iz Bet Haarabe; Azmavet iz Bahurima;"},{"v":32,"t":"Eljahba iz Šaalbona; Jašen, sin Jonatanov;"},{"v":33,"t":"Šama iz Harara; Ahiam, sin Šararov, iz Arara;"},{"v":34,"t":"Elifelet, sin Ahasbajev, iz Bet Maake; Eliam, sin Ahitofelov, iz Gilona;"},{"v":35,"t":"Hesraj iz Karmela; Paaraj iz Araba;"},{"v":36,"t":"Jigeal, sin Natanov, iz Sobe; Bani iz Gada;"},{"v":37,"t":"Selek Amonac; Nahraj iz Beerota, štitonoša Sarvijina sina Joaba;"},{"v":38,"t":"Ira iz Jatira; Gareb iz Jatira;"},{"v":39,"t":"Urija Hetit. Svega trideset i sedam."}]},"24":{"hr":[{"v":1,"t":"Još je jednom srdžba Jahvina planula na Izraelce te potakla Davida protiv njih govoreći: “Idi, izbroj Izraelce i Judejce!”"},{"v":2,"t":"I kralj zapovjedi Joabu i vojvodama koji bijahu s njim: “Obiđite sva Izraelova plemena od Dana do Beer Šebe i popišite narod da znam koliko ima naroda.”"},{"v":3,"t":"Joab odgovori kralju: “Neka Jahve, tvoj Bog, dade svome narodu još sto puta ovoliko koliko ga je sada i neka to još vidi svojim očima moj gospodar kralj, ali zašto moj gospodar kralj ima takvu želju?”"},{"v":4,"t":"Ali kraljeva riječ bijaše jača od Joabove i od riječi vojvoda njegove vojske. Tako Joab i vojvode odoše ispred kralja da popišu izraelski narod."},{"v":5,"t":"Prijeđoše oni preko Jordana i počeše kod Aroera i kod grada što leži usred doline i krenuše odande prema Gaditima i prema Jazeru."},{"v":6,"t":"Potom dođoše u Gilead i u zemlju Hetita, u Kadeš; zatim stigoše u Dan, a iz Dana skrenuše prema Sidonu."},{"v":7,"t":"Zatim dođoše do tvrđave Tira i u sve gradove Hivijaca i Kanaanaca i završiše svoj put u Negebu Judinu, u Beer Šebi."},{"v":8,"t":"Prošavši svu zemlju, vratiše se poslije devet mjeseci i dvadeset dana u Jeruzalem."},{"v":9,"t":"Joab dade kralju popis naroda: Izraelaca bijaše osam stotina tisuća ratnika vičnih maču, a Judejaca pet stotina tisuća ljudi."},{"v":10,"t":"Poslije toga Davida zapeče savjest što je dao brojiti narod pa reče Jahvi: “Veoma sam sagriješio što sam to učinio! Ali, Jahve, oprosti tu krivicu sluzi svome, jer sam vrlo ludo radio.”"},{"v":11,"t":"Kad je David ujutro ustao, već je Jahvina riječ bila došla proroku Gadu, Davidovu vidiocu:"},{"v":12,"t":"“Idi i kaži Davidu: Ovako govori Jahve: 'Troje stavljam preda te, izaberi jedno od toga da ti učinim!'”"},{"v":13,"t":"Gad tako dođe Davidu i javi mu ovo: “Hoćeš li da dođu tri gladne godine na tvoju zemlju, ili da tri mjeseca bježiš pred svojim neprijateljem koji će te goniti, ili da bude tri dana kuga u tvojoj zemlji? Sada promisli i gledaj što da odgovorim onome koji me poslao!”"},{"v":14,"t":"David odgovori Gadu: “Na velikoj sam muci! Ali neka padnemo u ruke Jahvine, jer je veliko njegovo milosrđe, a u ljudske ruke neka ne zapadnem!”"},{"v":15,"t":"David, dakle, izabra kugu. Bilo je upravo vrijeme pšenične žetve. Jahve pusti kugu na Izraela od jutra pa do određenoga vremena; i pomor udari na narod i pomrije sedamdeset tisuća ljudi od Dana do Beer Šebe."},{"v":16,"t":"Kad je anđeo pružio svoju ruku na Jeruzalem da ga uništi, sažali se Jahvi zbog toga zla, pa reče anđelu koji je ubijao narod: “Dosta je sada! Povuci svoju ruku!” A Jahvin je anđeo bio upravo kod gumna Araune Jebusejca."},{"v":17,"t":"Kad David vidje anđela koji je ubijao narod, zavapi Jahvi: “Evo, ja sam sagriješio, ja sam učinio zlo! A oni, ovce, što su skrivili? Neka tvoja ruka padne na mene i na moju obitelj!”"},{"v":18,"t":"Istoga dana dođe Gad k Davidu i reče mu: “Idi i podigni Jahvi žrtvenik na gumnu Araune Jebusejca!”"},{"v":19,"t":"I ode David po Gadovoj riječi, kako mu je zapovjedio Jahve."},{"v":20,"t":"Kad Arauna pogleda, opazi kralja i njegove dvorane gdje idu prema njemu. Arauna iziđe i pokloni se kralju licem do zemlje."},{"v":21,"t":"Arauna upita: “Zašto je moj gospodar kralj došao svome sluzi?” A David odgovori: “Da kupi od tebe ovo gumno, da sagradi žrtvenik Jahvi, kako bi prestao pomor u narodu.”"},{"v":22,"t":"Arauna reče Davidu: “Neka ga uzme moj gospodar kralj i neka žrtvuje ono što je u njegovim očima dobro! Evo goveda za paljenicu, mlatilice, i volujske opreme za drvo!"},{"v":23,"t":"Sve to sluga moga gospodara kralja poklanja kralju!” Još reče Arauna kralju: “Jahve, Bog tvoj, neka ti bude milostiv!”"},{"v":24,"t":"Ali kralj odgovori Arauni: “Ne, nego hoću da kupim od tebe i da platim; neću prinositi Jahvi, svome Bogu, paljenica koje su mi poklonjene.” I tako David kupi ono gumno i goveda za pedeset srebrnih šekela."},{"v":25,"t":"Ondje David sagradi žrtvenik Jahvi i prinese paljenice i pričesnice. Tada se Jahve smilova zemlji i presta pomor u Izraelu."}]}},"1KI":{"1":{"hr":[{"v":1,"t":"Kralj David bijaše ostario i odmakao u godinama; premda su ga pokrivali mnogim pokrivačima, nije se mogao ugrijati."},{"v":2,"t":"Tada mu rekoše njegove sluge: “Trebalo bi potražiti za gospodara mladu djevojku koja bi dvorila kralja i služila mu: kad bude spavala na njegovu krilu, to će ugrijati kralja gospodara.”"},{"v":3,"t":"Potražiše, dakle, lijepu djevojku po svoj zemlji izraelskoj; i nađoše Abišagu Šunamku te je dovedoše kralju."},{"v":4,"t":"Djevojka je bila izvanredno lijepa; njegovala je kralja i služila mu, ali je on ne upozna."},{"v":5,"t":"Uto se Adonija, sin Hagitin, pooholi i pomisli: “Ja ću biti kralj!” Zato nabavi sebi kola i konjanika i pedeset ljudi koji su išli pred njim."},{"v":6,"t":"Njegov ga otac za svoga života nikad nije ukorio niti ga kad upitao: “Zašto tako činiš?” Bio je, osim toga, stasit i lijep, a mati ga rodila poslije Abšaloma."},{"v":7,"t":"On se dogovarao s Joabom, sinom Sarvijinim, i sa svećenikom Ebjatarom, pa se obojica priključiše Adoniji."},{"v":8,"t":"Ali svećenik Sadok i Jojadin sin Benaja, prorok Natan, Šimej i Rei i junaci Davidovi ne pristadoše uz Adoniju."},{"v":9,"t":"Jednom nakla Adonija ovaca, volova i tovljene teladi za žrtvu kod Zoheledskog kamena, blizu izvora Rogela, te pozva svu svoju braću, sinove kraljeve, i sve Judejce u kraljevoj službi;"},{"v":10,"t":"ali ne pozva proroka Natana, ni Benaje, ni ostalih junaka, a ni svoga brata Salomona."},{"v":11,"t":"Tada reče Natan Bat-Šebi, majci Salomonovoj: “Zar nisi čula da je Adonija, sin Hagitin, postao kraljem, a da David, naš gospodar, o tome i ne zna?"},{"v":12,"t":"Dođi da te savjetujem kako bi mogla spasiti život svoj i svoga sina Salomona."},{"v":13,"t":"Hajde, otiđi kralju Davidu i reci mu: 'Zar se nisi ti, gospodaru moj kralju, zakleo svojoj službenici govoreći: Tvoj sin Salomon kraljevat će poslije mene, i on će sjediti na mome prijestolju! Kako sada Adonija posta kraljem?'"},{"v":14,"t":"I dok ti budeš ondje i razgovorala se s kraljem, doći ću ja za tobom i potvrditi tvoje riječi.”"},{"v":15,"t":"Bat-Šeba ode kralju u odaje - a on je bio vrlo star i Abišaga Šunamka služila mu."},{"v":16,"t":"Pokloni mu se Bat-Šeba i pade ničice pred kraljem, a kralj upita: “Što želiš?”"},{"v":17,"t":"Ona mu odgovori: “Gospodaru, ti si se zakleo službenici svojoj Jahvom, Bogom svojim: 'Tvoj sin Salomon kraljevat će poslije mene, on će sjesti na moje prijestolje.'"},{"v":18,"t":"A sada je, evo, Adonija postao kraljem, a ti, kralju, gospodaru moj, ništa o tome i ne znaš!"},{"v":19,"t":"Naklao je on mnogo volova, tovljene teladi i ovaca za žrtvu i pozvao je sve sinove kraljeve, svećenika Ebjatara i vojskovođu Joaba, ali slugu tvoga Salomona nije pozvao."},{"v":20,"t":"U tebe su sada, gospodaru moj i kralju, uprte oči svega Izraela da mu ti objaviš tko će te naslijediti na tvome prijestolju, kralju, gospodaru moj."},{"v":21,"t":"Inače, čim počine kralj, gospodar moj, kraj svojih otaca, ja i moj sin Salomon bit ćemo krivci.”"},{"v":22,"t":"Dok je ona još govorila s kraljem, dođe prorok Natan."},{"v":23,"t":"Javiše kralju: “Ovdje je prorok Natan.” On uđe kralju i pade ničice pred njim."},{"v":24,"t":"Natan reče: “Gospodaru moj i kralju, jesi li ti odredio: 'Adonija će kraljevati poslije mene i sjedit će na mome prijestolju?'"},{"v":25,"t":"Jer evo danas je sišao i naklao volova, ugojene teladi i ovaca za žrtvu i pozvao je sve sinove kraljeve, vojskovođe i svećenika Ebjatara; eno ih gdje jedu i piju s njim i kliču: 'Živio kralj Adonija!'"},{"v":26,"t":"Ali mene, tvoga slugu, svećenika Sadoka, a ni Benaju, sina Jojadina, ni tvoga slugu Salomona nije pozvao."},{"v":27,"t":"Zar se to dogodilo s voljom gospodara moga kralja, a da nisi obavijestio svoga vjernog sluge tko će biti nasljednik na prijestolju gospodara moga kralja?”"},{"v":28,"t":"Tada progovori David i reče: “Pozovite mi Bat-Šebu!” Ona dođe kralju i stupi preda nj."},{"v":29,"t":"Kralj se tada zakle: “Tako mi Jahve živoga koji me izbavio iz svih nevolja!"},{"v":30,"t":"Danas ću ti ispuniti kako sam ti se zakleo Jahvom, Bogom Izraelovim: tvoj će sin Salomon kraljevati poslije mene, on će sjediti na mome prijestolju!”"},{"v":31,"t":"Nato se nakloni Bat-Šeba licem do zemlje, pokloni se pred kraljem i reče: “Neka vječno živi gospodar moj kralj David!”"},{"v":32,"t":"A kralj David reče: “Pozovite mi svećenika Sadoka, proroka Natana i Benaju, sina Jojadina.” I dođoše oni pred kralja,"},{"v":33,"t":"a on im reče: “Uzmite sluge svoga gospodara sa sobom, posadite moga sina Salomona na moju mazgu i odvedite ga do Gihona."},{"v":34,"t":"Ondje neka ga svećenik Sadok i prorok Natan pomažu za kralja nad Izraelom. Zatrubite tada i obznanite: 'Živio kralj Salomon!'"},{"v":35,"t":"Zatim se uspnite amo s njim i neka uđe i sjedne na moje prijestolje i neka kraljuje mjesto mene, jer moja je volja: on neka bude glava nad Izraelom i nad Judom.”"},{"v":36,"t":"Benaja, sin Jojadin, reče kralju: “Amen - tako neka bude! To je i riječ Jahve, Gospodara kraljeva!"},{"v":37,"t":"Kao što je Jahve bio s mojim gospodarem kraljem, tako neka bude i sa Salomonom! Neka uzvisi prijestolje njegovo još više nego prijestolje kralja Davida, gospodara moga!”"},{"v":38,"t":"Svećenik Sadok, prorok Natan, Jojadin sin Benaja, Kerećani i Pelećani siđoše i posadiše Salomona na kraljevu mazgu i odvedoše ga na Gihon."},{"v":39,"t":"Svećenik Sadok donese iz Šatora rog s uljem i pomaza Salomona. Tada odjeknuše trube i sav narod povika: “Živio kralj Salomon!”"},{"v":40,"t":"I sav narod pođe za njim gore i sviraše puk u svirale i klicaše tako da se sva zemlja tresla."},{"v":41,"t":"Čuo to Adonija i svi njegovi uzvanici. Baš su bili pri kraju gozbe. I Joab je čuo trube pa upita: “Čemu ta buka u gradu?”"},{"v":42,"t":"Dok je on još govorio, stiže Jonatan, sin svećenika Ebjatara, i Adonija mu reče: “Ti si valjan čovjek, zacijelo nosiš dobru vijest!”"},{"v":43,"t":"Jonatan odgovori: “Jest, naš gospodar, kralj David, učinio je Salomona kraljem!"},{"v":44,"t":"Kralj je poslao s njim svećenika Sadoka, proroka Natana i Jojadina sina Benaju, i Kerećane i Pelećane. Oni ga posadiše na kraljevu mazgu,"},{"v":45,"t":"i svećenik Sadok i prorok Natan pomazaše ga na Gihonu za kralja. Zatim su sišli radosno kličući, i sav je grad uzavreo; to je buka koju ste čuli."},{"v":46,"t":"Još više: Salomon je već sjeo na kraljevsko prijestolje"},{"v":47,"t":"i došle su sluge kraljeve čestitati našem gospodaru kralju Davidu govoreći: 'Neka Bog tvoj proslavi ime Salomonovo više od imena tvoga i prijestolje njegovo uzvisi više od tvoga.' Kralj se tada poklonio na svojoj postelji"},{"v":48,"t":"i ovako rekao: 'Neka je blagoslovljen Jahve, Bog Izraelov, koji mi dade danas da mogu vidjeti svojim očima jednoga od mojih kako sjedi na mome prijestolju.'”"},{"v":49,"t":"Svi uzvanici Adonijini, uplašeni, ustadoše od stola i raziđoše se svaki svojim putem."},{"v":50,"t":"Adonija pak, u strahu od Salomona, usta i ode te se uhvati za rogove žrtvenika."},{"v":51,"t":"Javiše Salomonu: “Gle, Adonija se uplašio kralja Salomona i eno se drži za rogove žrtvenika govoreći: 'Neka mi se danas kralj Salomon zakune da neće sluge svoga mačem pogubiti.'”"},{"v":52,"t":"Salomon reče nato: “Ako se pokaže poštenim čovjekom, neće mu ni vlas s glave pasti na zemlju; a nađe li se u zlu, poginut će.”"},{"v":53,"t":"Tada zapovjedi Salomon da ga odmaknu od žrtvenika; on dođe i pade ničice pred Salomonom, koji mu reče: “Pođi svome domu!”"}]},"2":{"hr":[{"v":1,"t":"Kad su se dani Davidovi približavali svome svršetku, zapovjedi David svome sinu Salomonu:"},{"v":2,"t":"“Sada polazim na put sviju smrtnika. Ti budi hrabar i pokaži se čovjekom!"},{"v":3,"t":"Slušaj naredbe Jahve, Boga svoga, idi njegovim stazama, drži se njegovih zakona, zapovijedi, naredaba i njegovih pouka, kako je napisano u Zakonu Mojsijevu, da bi uspio u svemu što poduzmeš i svagdje kamo se okreneš;"},{"v":4,"t":"da bi Jahve ispunio svoje obećanje koje mi je dao: 'Ako sinovi tvoji budu pazili na svome putu, vjerno hodeći preda mnom, svim srcem svojim i svom dušom svojom, uvijek će jedan od njih sjediti na prijestolju Izraelovu.'"},{"v":5,"t":"I sam znaš što mi je učinio Joab, sin Sarvijin, kako je učinio obojici vojskovođa Izraelovih: Abneru, sinu Nerovu, i Amasi, sinu Jeterovu, kad ih je ubio i time prolio krv u miru kao u ratu te omastio krvlju pojas oko bokova svojih i obuću na nogama svojim."},{"v":6,"t":"Ti postupi po svom razboru i ne daj da mu sijeda kosa mirno počine u Podzemlju."},{"v":7,"t":"A sinovima Barzilaja Gileađanina vrati ljubav: neka budu među onima koji jedu za tvojim stolom jer su mi pomogli kad sam bježao pred tvojim bratom Abšalomom."},{"v":8,"t":"Pred sobom imaš Šimeja, sina Gerina, Benjaminovca iz Bahurima, koji me užasnim kletvama proklinjao onoga dana kad sam bježao u Mahanajim. Ali mi je on sišao u susret na Jordan i zakleh mu se Jahvom: 'Neću te pogubiti mačem.'"},{"v":9,"t":"Ali mu ti toga ne opraštaj, jer si čovjek razborit, i već ćeš znati kako treba da postupiš te mu sijedu kosu s krvlju u Podzemlje spremiš.”"},{"v":10,"t":"I potom počinu David kraj otaca svojih i bi pokopan u Davidovu gradu."},{"v":11,"t":"David je kraljevao nad Izraelom četrdeset godina: u Hebronu je kraljevao sedam godina, u Jeruzalemu je kraljevao trideset i tri godine."},{"v":12,"t":"Salomon sjede na prijestolje Davida, svoga oca, i njegova se vlast veoma učvrsti."},{"v":13,"t":"Ali Adonija, sin Hagitin, dođe Bat-Šebi, majci Salomonovoj, i pade ničice pred njom. Ona ga upita: “Je li miroljubiv tvoj dolazak?” On odgovori: “Jest, miroljubiv je.”"},{"v":14,"t":"I nastavi: “Imam ti nešto reći.” Ona reče: “Govori.”"},{"v":15,"t":"Tada će on: “Znaš i sama da je kraljevstvo pripadalo meni i da je sav Izrael očekivao da ću ja biti kralj. Ali mi je kraljevstvo izmaklo i pripalo je mome bratu, jer mu ga je Jahve namijenio."},{"v":16,"t":"Ja te sada samo jedno molim: nemoj me odbiti.” Ona reče: “Govori.”"},{"v":17,"t":"A on nastavi: “Reci, molim te, kralju Salomonu - jer tebe neće odbiti - neka mi dade za ženu Abišagu Šunamku!”"},{"v":18,"t":"A Bat-Šeba odgovori: “Dobro, govorit ću kralju o tebi.”"},{"v":19,"t":"Kada dakle uđe Bat-Šeba kralju Salomonu da govori o Adoniji, ustade kralj i pođe joj u susret, pokloni se pred njom, zatim sjede na svoje prijestolje i zapovjedi te namjestiše sjedalicu za kraljicu majku, i ona mu sjede s desne strane."},{"v":20,"t":"Tada mu reče: “Nešto bih zaiskala od tebe, nemoj me odbiti.” Kralj joj odgovori: “Traži, majko, jer te neću odbiti.”"},{"v":21,"t":"Ona nastavi: “Neka se dade Abišaga Šunamka tvome bratu Adoniji za ženu.”"},{"v":22,"t":"Kralj Salomon odgovori i reče svojoj majci: “Zašto tražiš Abišagu Šunamku za Adoniju? Traži odmah i kraljevstvo za njega! Jer on je moj stariji brat, a uz njega je svećenik Ebjatar i Joab, sin Sarvijin!”"},{"v":23,"t":"Tada se kralj Salomon zakle Jahvom: “Neka mi Bog učini ovo zlo i neka mi doda drugo ako Adonija nije to izrekao danas po cijenu svoga života!"},{"v":24,"t":"Živoga mi Jahve, koji me potvrdio i posadio na prijestolje oca moga Davida i koji mi je dao dom kako je obećao: još danas će Adonija umrijeti.”"},{"v":25,"t":"I kralj Salomon posla Benaju, sina Jojadina, koji ga udari te Adonija umrije."},{"v":26,"t":"Svećeniku Ebjataru kralj zatim naredi: “Idi u Anatot na svoj posjed. Zaslužio si smrt, ali te neću pogubiti danas jer si nosio Jahvin Kovčeg pred ocem mojim Davidom i podijelio si sve patnje s mojim ocem.”"},{"v":27,"t":"I Salomon isključi Ebjatara iz svećenstva Jahvina da tako ispuni Jahvinu riječ koju je izrekao protiv doma Elijeva u Šilu."},{"v":28,"t":"Kada je glas stigao Joabu - Joab bijaše pristao uz Adoniju, premda se nije priključio Abšalomu - on uteče u Šator Jahvin i uhvati se za rogove žrtvenika."},{"v":29,"t":"I dojaviše kralju Salomonu: “Joab je pobjegao u Šator Jahvin, eno ga pokraj žrtvenika.” Tada Salomon poruči Joabu: “Što se držiš žrtvenika?” Joab odgovori: “Uplašio sam se tebe i pobjegao sam pred Jahvu.” Tada Salomon naredi Benaji, sinu Jojadinu: “Idi i ubij ga!”"},{"v":30,"t":"Benaja ode u Šator Jahvin i reče Joabu: “Po naredbi kraljevoj: iziđi!” On odgovori: “Neću, želim ovdje umrijeti!” Benaja javi kralju: “Eto što mi je rekao Joab i što mi je odgovorio.”"},{"v":31,"t":"Kralj mu reče: “Učini kako je rekao: ubij ga, zatim pokopaj. Tako ćeš danas skinuti s mene i doma oca moga nevinu krv koju je Joab prolio."},{"v":32,"t":"Jahve će učiniti da krv njegova padne na njegovu glavu, jer je ubio dva čovjeka pravednika i bolja od sebe; ubio ih je mačem bez znanja moga oca Davida: Abnera, sina Nerova, vođu vojske Izraelove, i Amasu, sina Jeterova, vojvodu judejskoga."},{"v":33,"t":"Neka njihova krv padne na glavu Joaba i njegova potomstva dovijeka, a Davidu, njegovu potomstvu, vladalačkoj kući i prijestolju neka od Jahve bude trajan mir.”"},{"v":34,"t":"I ode Benaja, sin Jojadin, obori se na Joaba i usmrti ga. Pokopali su Joaba u njegovu domu u pustinji."},{"v":35,"t":"Mjesto njega postavi kralj na čelo vojske Benaju, sina Jojadina, a na mjesto Ebjatara postavi svećenika Sadoka."},{"v":36,"t":"Salomon pozva Šimeja i reče mu: “Sagradi sebi kuću u Jeruzalemu: tu stanuj, i nikamo odatle ne izlazi."},{"v":37,"t":"Onoga dana kad iziđeš i prijeđeš potok Kidron, znaj dobro da ćeš umrijeti. Krv tvoja na glavu tvoju.”"},{"v":38,"t":"Šimej odgovori kralju: “Dobro. Kako moj gospodar kralj kaže, tako će učiniti sluga tvoj.” I Šimej dugo življaše u Jeruzalemu."},{"v":39,"t":"Ali poslije tri godine dogodi se te Šimeju pobjegoše dvojica slugu k Akišu, sinu Maakinu, kralju gatskom. I dojaviše Šimeju: “Eno ti slugu u Gatu.”"},{"v":40,"t":"Tada usta Šimej, osedla magarca i ode u Gat, k Akišu, da traži svoje sluge. I vratio se Šimej i doveo svoje sluge iz Gata."},{"v":41,"t":"I javiše Salomonu: “Šimej otišao iz Jeruzalema u Gat i vratio se.”"},{"v":42,"t":"Kralj pozva Šimeja i reče mu: “Nisam li ti se zakleo Jahvom i strogo te opomenuo: 'Onoga dana kad budeš izišao i pošao bilo kamo, znaj dobro da ćeš umrijeti!' A ti si mi tada odgovorio: 'Dobra je riječ koju sam čuo.'"},{"v":43,"t":"Zašto nisi održao zakletvu Jahvinu i zapovijed koju sam ti dao?”"},{"v":44,"t":"Još reče kralj Šimeju: “Ti znaš sve zlo koje si učinio mome ocu Davidu. Tvoje je srce toga svjesno. Jahve neka učini da se tvoja zloća obori na tvoju glavu."},{"v":45,"t":"A blagoslovljen je kralj Salomon, i prijestolje će Davidovo biti čvrsto pred Jahvom dovijeka.”"},{"v":46,"t":"I zapovjedi kralj Benaji, sinu Jojadinu, te on iziđe i udari Šimeja i tako Šimej umrije. Tako se učvrstilo kraljevstvo u ruci Salomonovoj."}]},"3":{"hr":[{"v":1,"t":"Salomon se sprijatelji s faraonom, kraljem egipatskim: oženi se kćerju faraonovom i uvede je u Davidov grad dokle ne dovrši gradnju svoga dvora, Hrama Jahvina i zidova oko Jeruzalema."},{"v":2,"t":"Narod je pak prinosio žrtve na uzvišicama, jer još nije bio sagrađen do toga vremena dom imenu Jahvinu."},{"v":3,"t":"A Salomon je ljubio Jahvu: ravnao se prema naredbama svoga oca Davida, samo je prinosio klanice i kađenice na uzvišicama."},{"v":4,"t":"Kralj ode u Gibeon da prinese žrtvu, jer ondje bijaše najveća uzvišica. Salomon prinese tisuću paljenica na tom žrtveniku."},{"v":5,"t":"U Gibeonu se Jahve javi Salomonu noću u snu. Bog reče: “Traži što da ti dadem.”"},{"v":6,"t":"Salomon odgovori: “Veoma si naklon bio svome sluzi Davidu, mome ocu, jer je hodio pred tobom u vjernosti, pravednosti i poštenju srca svoga; i sačuvao si mu tu veliku milost i dao si da jedan od njegovih sinova sjedi na njegovu prijestolju."},{"v":7,"t":"Sada, o Jahve, Bože moj, ti si učinio kraljem slugu svoga na mjesto moga oca Davida, a ja sam još sasvim mlad te još ne znam vladati."},{"v":8,"t":"Tvoj je sluga usred naroda koji si izabrao; naroda brojnog, koji se ne da izbrojiti ni popisati."},{"v":9,"t":"Podaj svome sluzi pronicavo srce da može suditi tvom narodu, razlikovati dobro od zla, jer tko bi mogao upravljati tvojim narodom koji je tako velik!”"},{"v":10,"t":"Bijaše milo Jahvi što je Salomon to zamolio."},{"v":11,"t":"Zato mu Jahve reče: “Jer si to tražio, a nisi iskao ni duga života, ni bogatstva, ni smrti svojih neprijatelja, nego pronicavost u prosuđivanju pravice,"},{"v":12,"t":"evo ću učiniti po riječima tvojim: dajem ti srce mudro i razumno, kakvo nije imao nitko prije tebe niti će ga imati itko poslije tebe,"},{"v":13,"t":"ali ti dajem i što nisi tražio: bogatstvo i slavu kakve nema nitko među kraljevima."},{"v":14,"t":"I ako budeš stupao mojim putovima i budeš se držao mojih zakona i zapovijedi, kao što je činio tvoj otac David, umnožit ću tvoje dane.”"},{"v":15,"t":"Salomon se probudi, i gle: bijaše to san. On se vrati u Jeruzalem i stade pred Kovčeg saveza Jahvina; prinese paljenice i žrtve pričesnice i priredi gozbu svim slugama svojim."},{"v":16,"t":"Tada dođoše dvije bludnice kralju i stadoše preda nj."},{"v":17,"t":"I reče jedna žena: “Dopusti, gospodaru moj! Ja i ova žena u istoj kući živimo i ja sam rodila kraj nje u kući."},{"v":18,"t":"A trećega dana poslije moga porođaja rodi i ova žena. Bile smo zajedno i nikoga stranog s nama; samo nas dvije u kući."},{"v":19,"t":"Jedne noći umrije sin ove žene jer bijaše legla na njega."},{"v":20,"t":"I ustade ona usred noći, uze moga sina o boku mojem, dok je tvoja sluškinja spavala, i stavi ga sebi u naručje, a svoga mrtvog sina stavi kraj mene."},{"v":21,"t":"A kad ujutro ustadoh da podojim svoga sina, gle: on mrtav! I kad sam pažljivije pogledala, razabrah: nije to moj sin koga sam ja rodila!”"},{"v":22,"t":"Tada reče druga žena: “Ne, nije tako. Moj je sin onaj živi, a tvoj je onaj koji je mrtav!” A prva joj odvrati: “Nije istina! Tvoj je sin onaj koji je mrtav, a moj je onaj koji živi!” I tako se prepirahu pred kraljem."},{"v":23,"t":"A kralj onda progovori: “Ova kaže: 'Ovaj živi moj je sin, a onaj mrtvi tvoj'; druga pak kaže: 'Nije, nego je tvoj sin mrtav, a moj je onaj živi.'"},{"v":24,"t":"Donesite mi mač!” naredi kralj. I donesoše mač pred kralja,"},{"v":25,"t":"a on reče: “Rasijecite živo dijete nadvoje i dajte polovinu jednoj, a polovinu drugoj.”"},{"v":26,"t":"Tada ženu, majku živog djeteta, zabolje srce za sinom i povika ona kralju: “Ah, gospodaru! Neka se njoj dade dijete, samo ga nemojte ubijati!” A ona druga govoraše: “Neka ne bude ni meni ni tebi: rasijecite ga!”"},{"v":27,"t":"Onda progovori kralj i reče: “Dajte dijete prvoj, nipošto ga ne ubijajte! Ona mu je majka.”"},{"v":28,"t":"Sav je Izrael čuo presudu koju je izrekao kralj i poštovali su kralja, jer su vidjeli da je u njemu božanska mudrost u izricanju pravde."}]},"4":{"hr":[{"v":1,"t":"Kralj Salomon bio je kralj nad svim Izraelom,"},{"v":2,"t":"a evo njegovih odličnika: Azarja, sin Sadokov, svećenik;"},{"v":3,"t":"Elihoref i Ahija, sinovi Šišini, bilježnici; Jošafat, sin Ahiludov, savjetnik;"},{"v":4,"t":"Benaja, sin Jojadin, vojskovođa; Sadok i Ebjatar, svećenici."},{"v":5,"t":"Azarja, sin Natanov, bio je nad namjesnicima; Zabud, sin Natanov, prijatelj kraljev;"},{"v":6,"t":"Ahišar, upravitelj dvora; Eliab, sin Joabov, zapovjednik vojske; Adoram, sin Abdin, nadstojnik za tlaku."},{"v":7,"t":"Salomon je imao po svem Izraelu dvanaest namjesnika koji su opskrbljivali kralja i njegov dom; za svakoga je dolazio red da po jedan mjesec u godini podmiruje to uzdržavanje."},{"v":8,"t":"Evo njihovih imena: ...sin Hurov, u gori Efrajimovoj;"},{"v":9,"t":"...sin Dekerov, u Makasu, Šaalbimu, Bet Šemešu, Elonu do Bet Hanana;"},{"v":10,"t":"...sin Hesedov, u Arubotu; pod njim bijaše Soho i sav kraj heferski;"},{"v":11,"t":"...sin Abinadabov, nad svim okružjem dorskim; žena mu je bila Tafata, kći Salomonova;"},{"v":12,"t":"Baana, sin Ahiludov, u Tanaku i Megidu i u svem Bet Šeanu, koji je pokraj Saretana niže Jizreela, od Bet Šeana do Abel Mekole, i preko Jokmeama."},{"v":13,"t":"...sin Geberov, u Ramotu Gileadskom; njegova su bila Sela Jaira, sina Manašeova, koja su u Gileadu; imao je i područje Argob koje leži u Bašanu, šezdeset tvrdih gradova, opasanih zidovima i prijevornicama od tuča;"},{"v":14,"t":"Ahinabad, sin Idov, u Mahanajimu;"},{"v":15,"t":"Ahimaas u Naftaliju; i on se oženio jednom Salomonovom kćeri - Bosmatom."},{"v":16,"t":"Baana, sin Hušajev, u Ašeru i na visoravnima;"},{"v":17,"t":"Jošafat, sin Paruahov, u Jisakaru;"},{"v":18,"t":"Šimej, sin Elin, u Benjaminu;"},{"v":19,"t":"Geber, sin Urijin, u zemlji Gileadu, zemlji Sihona, kralja amorejskoga, i Oga, kralja bašanskoga. Povrh toga bio je još jedan namjesnik u zemlji."},{"v":20,"t":"Juda i Izrael bili su mnogobrojni, bijaše ih kao pijeska na obali morskoj. Jeli su i pili i bili sretni."}]},"5":{"hr":[{"v":1,"t":"Salomon je proširio svoju vlast nad svim kraljevstvima od Rijeke sve do zemlje filistejske i do međe egipatske. Ona su donosila svoj danak i služila Salomonu sve dane njegova života."},{"v":2,"t":"Svakoga je dana trebalo Salomonu za hranu: trideset kora finoga brašna i šezdeset kora običnog brašna,"},{"v":3,"t":"deset ugojenih volova, dvadeset volova s paše, stotinu ovaca, osim jelena, srna, divokoza i ugojene peradi."},{"v":4,"t":"Jer on je vladao nad svime onkraj Rijeke - od Tafse do Gaze, nad svim kraljevima s onu stranu Eufrata - i imao je mir po svim granicama naokolo."},{"v":5,"t":"Juda i sav Izrael živjeli su bez straha, svaki pod svojom lozom i pod svojom smokvom, od Dana sve do Beer Šebe, svega vijeka Salomonova."},{"v":6,"t":"Salomon je imao četrdeset tisuća konja za vuču i dvanaest tisuća za jahanje."},{"v":7,"t":"Ti su se namjesnici brinuli o opskrbi kralja Salomona i sviju koji su imali dijela za kraljevim stolom, svaki po mjesec dana; i nisu dopuštali da ičega ponestane."},{"v":8,"t":"I ječam i slamu za konje i tegleću marvu donosili su na mjesto gdje se zadržavao, svaki kako bi ga zapalo."},{"v":9,"t":"Jahve je dao Salomonu mudrost i izuzetnu razboritost i srce široko kao pijesak na obali morskoj."},{"v":10,"t":"Mudrost je Salomonova bila veća od mudrosti svih sinova Istoka i od sve mudrosti Egipta."},{"v":11,"t":"Bio je mudriji od svih ljudi, od Etana Ezrahanina, od Hemana, Kalkola i Darde, sinova Maholovih; njegovo se ime pronosilo među svim narodima unaokolo."},{"v":12,"t":"Izrekao je tri tisuće mudrih izreka, a njegovih je pjesama bilo tisuću i pet."},{"v":13,"t":"Zborio je o drveću: od cedra što je na Libanonu pa do izopa što klija na zidu; raspravljao je o životinjama, o pticama, o gmazovima i o ribama."},{"v":14,"t":"Dolazili su od sviju naroda da čuju mudrost Salomonovu, od svih zemaljskih kraljeva koji su čuli glas o njegovoj mudrosti."},{"v":15,"t":"Tirski kralj Hiram posla svoje sluge Salomonu, jer bijaše čuo da su ga pomazali za kralja na mjesto njegova oca, a Hiram je svagda bio prijatelj Davidov."},{"v":16,"t":"Tada Salomon poruči Hiramu:"},{"v":17,"t":"“Ti znaš dobro da moj otac David nije mogao sagraditi Doma imenu Jahve, svoga Boga, zbog ratova kojima su ga okružili neprijatelji sa svih strana, sve dok ih Jahve nije položio pod stopala nogu njegovih."},{"v":18,"t":"Sada mi je Jahve, Bog moj, dao mir posvuda unaokolo: nemam neprijatelja ni zlih udesa."},{"v":19,"t":"Namjeravam, dakle, sagraditi Dom imenu Jahve, Boga svoga, kako je Jahve rekao mome ocu Davidu: 'Tvoj sin koga ću mjesto tebe postaviti na tvoje prijestolje, on će sagraditi Dom mome Imenu.'"},{"v":20,"t":"Stoga sada zapovjedi da mi nasijeku cedrova na Libanonu; moje će sluge biti sa slugama tvojim, i ja ću platiti nadnicu tvojim slugama prema svemu kako mi odrediš. Ti znaš dobro da u nas nema ljudi koji umiju sjeći drva kao Sidonci.”"},{"v":21,"t":"Kada je Hiram primio Salomonovu poruku, veoma se obradova i reče: “Neka je blagoslovljen danas Jahve koji je dao mudra sina Davidu, koji upravlja ovim velikim narodom.”"},{"v":22,"t":"I Hiram javi Salomonu: “Primio sam tvoju poruku. Ispunit ću u svemu tvoju želju glede drva cedrova i drva čempresova."},{"v":23,"t":"Moje će ih sluge dopremiti s Libanona na more, složit ću ih u splavi i pustiti ih morem do mjesta koje ćeš mi označiti; ondje ću ih razložiti i ti ćeš ih uzeti. Ti ćeš pak ispuniti moju želju i dati hranu mojoj čeljadi.”"},{"v":24,"t":"Hiram je davao Salomonu drva cedrova i čempresova koliko je htio,"},{"v":25,"t":"a Salomon je davao Hiramu dvadeset tisuća kora pšenice za hranu ljudstvu, i dvadeset tisuća kora ulja od tiještenih maslina. Toliko je Salomon davao Hiramu godinu za godinom."},{"v":26,"t":"Jahve je dao mudrost Salomonu, kako mu bijaše obećao; između Hirama i Salomona vladao je mir te oni sklopiše savez."},{"v":27,"t":"Tada diže kralj Salomon kulučare iz svega Izraela; kulučara je bilo u svemu trideset tisuća ljudi."},{"v":28,"t":"Slao ih je naizmjence na Libanon, svakog mjeseca deset tisuća ljudi: bili su mjesec dana na Libanonu, a dva mjeseca kod kuće. Adoniram je bio nad svim kulučarima."},{"v":29,"t":"Salomon je imao i sedamdeset tisuća nosača tereta, osamdeset tisuća kamenorezaca u gori,"},{"v":30,"t":"ne računajući glavara službeničkih koji su upravljali poslovima; njih je bilo tri tisuće i tri stotine, a upravljali su narodom zaposlenim na radovima."},{"v":31,"t":"Kralj je zapovjedio da lome gromade biranog kamena i da ih klešu za temelje Hrama."},{"v":32,"t":"Graditelji Salomonovi i Hiramovi, i oni iz Gibela, tesali su i pripremali drvo i klesali za gradnju Hrama."}]},"6":{"hr":[{"v":1,"t":"Četiri stotine i osamdesete godine poslije izlaska Izraelaca iz zemlje egipatske, četvrte godine kraljevanja svoga nad Izraelom, mjeseca Ziva - to je drugi mjesec - počeo je Salomon graditi Dom Jahvin."},{"v":2,"t":"Hram što ga je kralj Salomon gradio Jahvi bio je dug šezdeset lakata, širok dvadeset, a visok dvadeset i pet lakata."},{"v":3,"t":"Trijem pred Hekalom Hrama bio je dvadeset lakata dug, prema širini Hrama, a deset lakata širok, prema dužini Hrama."},{"v":4,"t":"Na Hramu je napravio prozore zatvorene rešetkama."},{"v":5,"t":"Uza zid Hrama oko Hekala i Debira sagradio je prigradnju na katove, sve unaokolo."},{"v":6,"t":"Donji kat bio je pet lakata širok, srednji šest, a treći sedam lakata, jer je zasjeke rasporedio s vanjske strane naokolo Hrama da ih ne bi morao ugrađivati u hramske zidove."},{"v":7,"t":"Hram je građen od kamena koji je već u kamenolomu bio oklesan, tako da se za gradnje nije čuo ni čekić ni dlijeto, ni ikakvo željezno oruđe."},{"v":8,"t":"Ulaz u donji kat bio je s desne strane Hrama, a zavojnim se stubama uspinjalo na srednji kat i sa srednjega na treći."},{"v":9,"t":"Sagradio je tako Hram i dovršio ga; i pokrio ga cedrovim gredama i daskama."},{"v":10,"t":"I sagradi još prigradnju oko cijeloga Hrama; bila je pet lakata visoka, a vezana s Hramom cedrovim gredama."},{"v":11,"t":"I riječ Jahvina stiže Salomonu:"},{"v":12,"t":"“To je Dom što ga gradiš ... Ako budeš hodio prema naredbama mojim, ako budeš vršio naredbe moje i držao se mojih zapovijedi, tada ću ispuniti tebi obećanje što sam ga dao tvome ocu Davidu:"},{"v":13,"t":"prebivat ću među sinovima Izraelovim i neću ostaviti naroda svoga Izraela.”"},{"v":14,"t":"I tako Salomon sazida Hram i dovrši ga."},{"v":15,"t":"I obloži iznutra zidove Hrama cedrovim daskama - od poda do stropa obloži ih drvetom iznutra - a daskama čempresovim obloži pod Hrama."},{"v":16,"t":"I načini pregradu od dvadeset lakata, od cedrovih dasaka, s poda pod strop, i odijeli taj dio Hrama za Debir, za Svetinju nad svetinjama."},{"v":17,"t":"A Hekal - Svetište, dio Hrama ispred Debira - imaše četrdeset lakata."},{"v":18,"t":"A po cedrovini unutar Hrama bijahu urezani ukrasi - pleteri od pupoljaka i cvijeća; sve je bilo od cedrovine i nigdje se nije vidio kamen."},{"v":19,"t":"Debir je uredio unutra u Hramu da onamo smjesti Kovčeg saveza Jahvina."},{"v":20,"t":"Debir bijaše dvadeset lakata dug, dvadeset lakata širok i dvadeset lakata visok, a obložio ga je čistim zlatom. Napravio je i Žrtvenik od cedrovine,"},{"v":21,"t":"pred Debirom, i obložio ga čistim zlatom."},{"v":22,"t":"I sav je Hram obložio zlatom, sav Hram i sav oltar koji je pred Debirom obložio je zlatom."},{"v":23,"t":"U Debiru načini dva kerubina od maslinova drveta. Bili su visoki deset lakata."},{"v":24,"t":"Jedno je krilo u kerubina bilo pet lakata i drugo je krilo u kerubina bilo pet lakata; deset je lakata bilo od jednoga kraja krila do drugoga."},{"v":25,"t":"I drugi je kerubin bio od deset lakata: jednaka mjera i jednak oblik obaju kerubina."},{"v":26,"t":"Visina jednog kerubina bila je deset lakata, tako i drugoga."},{"v":27,"t":"Smjestio je kerubine usred nutarnje prostorije; širili su svoja krila, tako da je krilo jednoga ticalo jedan zid, a krilo drugoga ticalo drugi zid; u sredini prostorije krila im se doticahu."},{"v":28,"t":"I kerubine je obložio zlatom."},{"v":29,"t":"Po svim zidovima Hrama unaokolo, iznutra i izvana, urezao je likove kerubina, palma i rastvorenih cvjetova,"},{"v":30,"t":"zlatom je pokrio i pod Hramu iznutra i izvana."},{"v":31,"t":"A za ulaz u Debir načini dvokrilna vrata od maslinova drveta; dovraci s pragom bijahu na pet uglova."},{"v":32,"t":"Oba krila na vratima od maslinova drveta ukrasi likovima kerubina, palma i rastvorenih cvjetova, i sve ih obloži zlatom; listićima zlata oblijepi kerubine i palme."},{"v":33,"t":"Tako i za ulaz u Hekal načini vrata od maslinova drveta, sa četverokutnim dovracima."},{"v":34,"t":"Oba krila na vratima bijahu od čempresova drveta i oba se otvarahu na jednu i na drugu stranu."},{"v":35,"t":"Urezao je na njima kerubine, palme i rastvorene cvjetove i obložio zlatom sve što bijaše urezano."},{"v":36,"t":"Potom je sagradio unutrašnje predvorje od tri reda klesanog kamena i jednoga reda tesanih greda cedrovih."},{"v":37,"t":"Temelji su Hramu Jahvinu bili položeni četvrte godine, mjeseca Ziva;"},{"v":38,"t":"a jedanaeste godine, mjeseca Bula - to je osmi mjesec - Hram je dovršen sa svim dijelovima i sa svim što mu pripada. Salomon ga sagradi za sedam godina."}]},"7":{"hr":[{"v":1,"t":"Salomon je sagradio i svoj dvor; u trinaest ga je godina potpuno dovršio."},{"v":2,"t":"Sagradio je dvor od libanonske šume: stotinu lakata dug, pedeset širok i trideset lakata visok, na četiri reda cedrovih stupova, a na stupovima bijahu cedrove grede."},{"v":3,"t":"Bio je pokriven cedrovinom iznad soba koje su počivale na stupovima. Ovih je bilo četrdeset i pet: petnaest u svakom redu."},{"v":4,"t":"Bila su tri reda prozora: po tri su prozora gledala jedan prema drugome."},{"v":5,"t":"Sva vrata s dovratnicima bila su četverokutna i po tri su prozora stajala jedan prema drugome."},{"v":6,"t":"Načinio je trijem od stupova, pedeset lakata dug i trideset širok."},{"v":7,"t":"Zatim je sagradio prijestolni trijem gdje je sudio; i sudački trijem, obložen cedrovinom od poda do stropa."},{"v":8,"t":"Njegovo prebivalište, u drugom dvorištu i unutar predvorja, bilo je istoga oblika. Sagradio je i kuću, nalik na onaj trijem, faraonovoj kćeri, kojom se bijaše oženio."},{"v":9,"t":"Sve su te građevine bile od biranog kamena, sječena po mjeri, a klesana iznutra i izvana, od temelja sve do drvenih spojnica, a vani sve do velikog predvorja."},{"v":10,"t":"Temelji su im bili od birana, velikog kamena: od deset i od osam lakata,"},{"v":11,"t":"a nadgradnja od birana, po mjeri klesana kamena i od cedrovine."},{"v":12,"t":"A tri su reda klesanog kamena i red cedrovih greda okruživali veliko predvorje, a tako i unutrašnje predvorje Doma Jahvina."},{"v":13,"t":"Salomon posla po Hirama iz Tira."},{"v":14,"t":"Bio je to sin udovice iz plemena Naftalijeva, ali mu otac bijaše iz Tira, kovač tuča. Bio je pun vještine, umijeća i znanja da svašta izrađuje od tuča. Dođe on kralju Salomonu i sav mu posao izradi."},{"v":15,"t":"Salio je dva stupa od tuča; jedan je stup bio visok osamnaest lakata, a koncem mjeren unaokolo imao je dvanaest lakata, isto tako i drugi."},{"v":16,"t":"I načini dvije glavice od tuča da se stave povrh stupova; jedna je glavica bila visoka pet lakata i druga je bila pet lakata visoka."},{"v":17,"t":"Načini dva opleta u obliku pletera i lančaste žice da pokriju glavice na vrhu stupova; sedam za jednu glavicu i sedam za drugu."},{"v":18,"t":"Onda izradi mogranje: bili su u dva reda oko svake mreže."},{"v":19,"t":"Glavice na vrhu stupova pred trijemom imale su oblik ljiljana, od četiri lakta."},{"v":20,"t":"Stajale su na oba stupa kod izbočine što je bila prema lančancu. Dvije stotine mogranja bilo je oko prve glavice i dvije stotine oko druge."},{"v":21,"t":"Podiže stupove pred trijemom Hekala; jedan postavi na desnu stranu i nazva ga Jahin; postavi drugi stup na lijevu stranu i dade mu ime Boaz."},{"v":22,"t":"Na samom vrhu stupova postavi izrađene ljiljane. I tako dovrši stupove."},{"v":23,"t":"Tada od rastaljene kovine izli more koje je od ruba do ruba mjerilo deset lakata; bilo je okruglo naokolo, pet lakata visoko, a u opsegu, mjereno vrpcom, imalo je trideset lakata."},{"v":24,"t":"Pod rubom mu bijahu uresi kao cvjetne čaške koje su ga optakale sasvim: po deset na lakat optakale su more unaokolo; cvjetne su čaške bile u dva reda i salivene s njim."},{"v":25,"t":"Počivalo je na dvanaest volova: tri su gledala na sjever, tri na zapad, tri na jug, a tri na istok; more je stajalo na njima i svi su stražnjim dijelom bili okrenuti unutra."},{"v":26,"t":"Bilo je debelo pedalj, rub mu kao rub u čaše, kao cvijet, a moglo je primiti tri tisuće bata."},{"v":27,"t":"Načinio je deset tučanih podnožja; svako je podnožje bilo četiri lakta dugo, četiri lakta široko, a tri lakta visoko."},{"v":28,"t":"Podnožja su bila ovako izrađena: imala su okvire, a okviri su stajali među preponama."},{"v":29,"t":"Na okvirima među preponama bili su lavovi, volovi i kerubini; a na samim preponama, kako iznad lavova i volova tako i pod njima, bijahu ukrasi poput vijenaca."},{"v":30,"t":"Svako je podnožje imalo četiri tučana točka i osovine od tuča; četiri su njihove noge imale držače; pod umivaonikom bijahu držači sliveni s ukrasima."},{"v":31,"t":"Gore, gdje su se držači sastavljali, bio je otvor podnožja; imao je lakat i pol; otvor je bio okrugao, u obliku ukrasne posude, a na njemu su bili uklesani i ukrasi; ali prepone bijahu četvrtaste, a ne okrugle."},{"v":32,"t":"Četiri su točka bila pod preponom. Osovine im izlazile na podnožju; svaki točak bijaše visok lakat i pol."},{"v":33,"t":"Točkovi su bili slični točkovima običnih kola: njihove osovine, naplaci, paoci i glavčine - sve bijaše liveno."},{"v":34,"t":"Bila su četiri držača na četiri ugla svakog podnožja; podnožje i držači sačinjavahu jednu cjelinu."},{"v":35,"t":"Pri vrhu podnožja bio je sve unaokolo krug visok pol lakta; povrh podnožja bili su klinovi; prepone su s njima sačinjavale cjelinu."},{"v":36,"t":"Po oplošjima klinova i prepona urezao je kerube, lavove i palme, već prema veličini praznog oplošja i vijenaca naokolo."},{"v":37,"t":"Tako načini deset podnožja: jednako salivenih, jednake veličine i oblika."},{"v":38,"t":"I načini deset umivaonika od tuča. Svaki je umivaonik sadržavao četrdeset bata, a svaki je umivaonik bio od četiri lakta; na svako od deset podnožja došao je po jedan umivaonik."},{"v":39,"t":"Postavi pet podnožja na desnoj strani Hrama, a pet na lijevoj strani Hrama; a more stavi s desne strane Hrama, prema jugoistoku."},{"v":40,"t":"Hiram načini lonce, lopate i kotliće. Dovrši on sav posao što ga je obavljao kralju Salomonu za Dom Jahvin:"},{"v":41,"t":"dva stupa, okrugle glavice što su bile navrh stupova; dva opleta da pokriju dvije glavice što bijahu navrh stupova;"},{"v":42,"t":"četiri stotine mogranja za oba opleta; dva reda mogranja za svaki oplet da prekriju dvije glavice navrh stupova;"},{"v":43,"t":"deset podnožja i deset umivaonika na podnožjima;"},{"v":44,"t":"jedno more i dvanaest volova pod njim;"},{"v":45,"t":"lonce, lopate i kotliće. Svi ti predmeti koje je Hiram načinio kralju Salomonu za Dom Jahvin bili su od sjajnog tuča."},{"v":46,"t":"Kralj je zapovjedio da sve to lijevaju u kalupima od gline, u Jordanskoj dolini, između Sukota i Sartana."},{"v":47,"t":"Na koncu je Salomon odredio da rasporede sve te predmete, a bijaše ih toliko da se nije mogla obračunati težina tuča."},{"v":48,"t":"Salomon načini sve predmete koji su bili u Domu Jahvinu: zlatni žrtvenik i zlatni stol na kojemu su stajali prineseni hljebovi;"},{"v":49,"t":"pet svijećnjaka s desne i pet s lijeve strane pred Debirom, od čistoga zlata; cvjetove, svjetiljke, usekače od zlata;"},{"v":50,"t":"vrčeve, noževe, kotliće, plitice i kadionice od čistoga zlata; stožere za vrata nutarnje dvorane - to je Svetinja nad svetinjama - i za vrata Hekala - to jest Hrama - sve od zlata."},{"v":51,"t":"Tako bi priveden kraju sav posao što ga Salomon obavi za Dom Jahvin. Salomon unese sve svete darove oca svoga Davida - srebro, zlato i posuđe - i stavi ih u riznicu Doma Jahvina."}]},"8":{"hr":[{"v":1,"t":"Tada Salomon sazva u Jeruzalem sve starješine Izraelove, sve knezove plemenske i glavare obitelji da se prenese Kovčeg saveza Jahvina iz grada, Davidova grada, to jest sa Siona."},{"v":2,"t":"Svi se ljudi Izraelovi sabraše pred kraljem Salomonom na blagdan u mjesecu Etanimu (to je sedmi mjesec)."},{"v":3,"t":"I kad su došle Izraelove starješine, svećenici ponesoše Kovčeg"},{"v":4,"t":"i Šator sastanka sa svim posvećenim priborom što bješe u Šatoru. Prenosili su ih svećenici i leviti."},{"v":5,"t":"Kralj Salomon i sva zajednica Izraelova koja se sabrala oko njega žrtvovali su pred Kovčegom toliko ovaca i goveda da se ne mogahu prebrojiti ni procijeniti."},{"v":6,"t":"Svećenici donesoše Kovčeg saveza Jahvina na njegovo mjesto, u Debir Doma, to jest u Svetinju nad svetinjama, pod krila kerubina."},{"v":7,"t":"Kerubini su, naime, imali raširena krila nad mjestom gdje stajaše Kovčeg i zaklanjahu odozgo Kovčeg i njegove motke."},{"v":8,"t":"[8a] Motke su bile tako dugačke da su im se krajevi vidjeli iz Svetišta nasuprot Debiru, ali se nisu vidjele izvana."},{"v":9,"t":"U Kovčegu nije bilo ništa, osim dviju kamenih ploča koje metnu Mojsije na Horebu, gdje Jahve sklopi Savez s Izraelcima pošto iziđoše iz Egipta. [8b] Ondje su ostale do danas."},{"v":10,"t":"A kad su svećenici izašli iz Svetišta, oblak ispuni Dom Jahvin,"},{"v":11,"t":"i svećenici ne mogoše od oblaka nastaviti službe: slava Jahvina ispuni Dom Božji!"},{"v":12,"t":"Tada reče Salomon: “Jahve odluči prebivati u tmastu oblaku,"},{"v":13,"t":"a ja ti sagradih uzvišen Dom da u njemu prebivaš zauvijek.”"},{"v":14,"t":"I, okrenuvši se, kralj blagoslovi sav izraelski zbor, a sav je izraelski zbor stajao."},{"v":15,"t":"Reče on: “Neka je blagoslovljen Jahve, Bog Izraelov, koji je svojom rukom ispunio obećanje što ga na svoja usta dade ocu mome Davidu, rekavši:"},{"v":16,"t":"'Od dana kad izvedoh svoj narod iz zemlje egipatske, nisam izabrao grada ni iz kojega Izraelova plemena da se u njemu sagradi Dom gdje bi prebivalo moje Ime, nego sam izabrao Davida da on zapovijeda mojim narodom Izraelom.'"},{"v":17,"t":"Otac mi David naumi podići Dom Imenu Jahve, Boga Izraelova,"},{"v":18,"t":"ali mu Jahve reče: 'Naumio si podići Dom mojem Imenu, i dobro učini,"},{"v":19,"t":"ali nećeš ti podići toga Doma, nego sin tvoj koji izađe iz tvoga krila, on će podići Dom mojem Imenu.'"},{"v":20,"t":"Jahve ispuni obećanje svoje: naslijedio sam svoga oca Davida i sjeo na prijestolje Izraelovo, kako obeća Jahve, i podigao Dom Imenu Jahve, Boga Izraelova,"},{"v":21,"t":"i odredio sam da ondje bude mjesto Kovčegu u kojem je Savez što ga Jahve sklopi s našim ocima kad ih je izveo iz zemlje egipatske.”"},{"v":22,"t":"Tada Salomon stupi, u nazočnosti svega zbora Izraelova, pred žrtvenik Jahvin, raširi ruke prema nebu"},{"v":23,"t":"i reče: “Jahve, Bože Izraelov! Nijedan ti bog nije sličan ni na nebesima ni dolje na zemlji, tebi koji držiš Savez i ljubav svojim slugama što kroče pred tobom sa svim svojim srcem."},{"v":24,"t":"Sluzi svome Davidu, mome ocu, ti si ispunio što si mu obećao. Što si obećao na svoja usta, ispunio si svojom rukom upravo danas."},{"v":25,"t":"Sada, Jahve, Bože Izraelov, ispuni svome sluzi, ocu mome Davidu, što si obećao kad si rekao: 'Neće ti preda mnom nestati nasljednika koji bi sjedio na izraelskom prijestolju, samo ako tvoji sinovi budu čuvali svoje putove hodeći po mojem zakonu kako si ti hodio preda mnom.'"},{"v":26,"t":"Sada, dakle, Jahve, Bože Izraelov, neka se ispuni tvoje obećanje koje si dao svome sluzi Davidu, mome ocu!"},{"v":27,"t":"Ali zar će Bog doista boraviti s ljudima na zemlji? TÓa nebesa ni nebesa nad nebesima ne mogu ga obuhvatiti, a kamoli ovaj Dom što sam ga sagradio!"},{"v":28,"t":"Pomno počuj molitvu i vapaj svoga sluge, Jahve, Bože moj, te usliši vapaj i molitvu što je tvoj sluga tebi upućuje!"},{"v":29,"t":"Neka tvoje oči obdan i obnoć budu otvorene nad ovim Domom, nad ovim mjestom za koje reče: 'Tu će biti moje Ime.' Usliši molitvu koju će sluga tvoj izmoliti na ovome mjestu."},{"v":30,"t":"I usliši molitvu sluge svoga i naroda svojega izraelskog koju bude upravljao prema ovome mjestu. Usliši s mjesta gdje prebivaš, s nebesa; usliši i oprosti."},{"v":31,"t":"Ako tko zgriješi protiv bližnjega i naredi mu se da se zakune, a zakletva dođe pred tvoj žrtvenik u ovom Domu,"},{"v":32,"t":"tada je ti čuj u nebu i postupaj i sudi svojim slugama, osudi krivca okrećući njegova djela na njegovu glavu, a nevina oslobodi postupajući s njime po nevinosti njegovoj."},{"v":33,"t":"Ako narod tvoj bude potučen od neprijatelja jer se ogriješio o tebe, ali se ipak k tebi obrati i proslavi Ime tvoje i u ovom se Domu pomoli,"},{"v":34,"t":"onda ti čuj to s neba, oprosti grijehe svome narodu izraelskom i dovedi ga natrag u zemlju koju si dao njihovim očevima."},{"v":35,"t":"Kad se zatvori nebo i ne padne kiša jer su se ogriješili o tebe, pa ti se pomole na ovome mjestu i proslave Ime tvoje i obrate se od svojega grijeha kad ih ti poniziš,"},{"v":36,"t":"tada ti čuj na nebu i oprosti grijeh svojim slugama i svojem izraelskom narodu, pokazujući im valjan put kojim će ići, i pusti kišu na zemlju koju si svojem narodu dao u baštinu."},{"v":37,"t":"Kad u zemlji zavlada glad, kuga, snijet i rđa i kad navale skakavci, gusjenice, kad neprijatelj ovoga naroda pritisne koja od njegovih vrata, ili kad bude kakva druga nevolja ili boleština,"},{"v":38,"t":"ako koji čovjek, ili sav tvoj narod, Izrael, osjeti tjeskobu svoga srca pa upravi molitvu ili prošnju te raširi ruke prema ovom Hramu,"},{"v":39,"t":"ti čuj s neba, s mjesta gdje prebivaš, i oprosti i postupi; vrati svakome čovjeku prema putu njegovu, jer ti poznaješ srce njegovo - ti jedini poznaješ srce sviju -"},{"v":40,"t":"da te se uvijek boje sve dane dokle žive na zemlji što je ti dade našim očevima."},{"v":41,"t":"Pa i tuđinca, koji nije od tvojega naroda izraelskog, nego je stigao iz daleke zemlje radi Imena tvoga"},{"v":42,"t":"jer je čuo za veliko Ime tvoje, za tvoju snažnu ruku i za tvoju mišicu podignutu - ako dođe i pomoli se u ovom Hramu,"},{"v":43,"t":"usliši ga s neba gdje prebivaš, usliši sve vapaje njegove da bi upoznali svi zemaljski narodi Ime tvoje i bojali se tebe kao narod tvoj Izrael i da znaju da je tvoje Ime zazvano nad ovaj Dom koji sam sagradio."},{"v":44,"t":"Ako narod tvoj krene na neprijatelja putem kojim ga ti uputiš i pomoli se Jahvi, okrenut k ovom gradu što si ga izabrao i prema Domu koji sam podigao tvojem Imenu,"},{"v":45,"t":"usliši mu s neba molitvu i prošnju i učini mu pravdu."},{"v":46,"t":"Kad ti sagriješe, jer nema čovjeka koji ne griješi, a ti ih, rasrdiv se na njih, predaš neprijateljima da ih zarobe i odvedu kao roblje u daleku ili blizu zemlju,"},{"v":47,"t":"pa ako se pokaju srcem u zemlji u koju budu dovedeni te se obrate i počnu te moliti za milost u zemlji svojih osvajača govoreći: 'Zgriješili smo, bili smo zli i naopaki',"},{"v":48,"t":"i tako se obrate k tebi svim srcem i svom dušom u zemlji svoga ropstva u koju budu dovedeni kao roblje, i pomole se okrenuti k zemlji što je ti dade njihovim očevima, i prema gradu koji si izabrao, i prema Domu što sam ga podigao tvom Imenu,"},{"v":49,"t":"usliši s neba, gdje prebivaš, njihovu molbu i njihove prošnje,"},{"v":50,"t":"učini im pravdu i oprosti svome narodu što je zgriješio protiv tebe, oprosti sve uvrede koje ti je nanio, učini da mu se smiluju osvajači i da budu milostivi prema njemu,"},{"v":51,"t":"jer su oni tvoj narod i baština tvoja, njih si izveo iz Egipta, iz užarenog kotla."},{"v":52,"t":"Neka oči tvoje budu otvorene na prošnju tvoga sluge i na prošnju naroda tvoga Izraela da čuješ sve njihove molbe što će ih tebi uputiti."},{"v":53,"t":"Jer ti si ih odvojio od svih naroda na zemlji sebi za baštinu, kako si objavio po svome sluzi Mojsiju, kada si izveo oce naše iz Egipta, o Gospode, Jahve!”"},{"v":54,"t":"Pošto je Salomon dovršio svu ovu molitvu i prošnju pred Jahvom, diže se s mjesta gdje je klečao, raširenih ruku prema nebu, pred žrtvenikom Jahvinim,"},{"v":55,"t":"pa istupi te blagoslovi sav zbor Izraelov govoreći jakim glasom:"},{"v":56,"t":"“Blagoslovljen Jahve, koji je narodu svome Izraelu dao mir u svemu kako je obećao; nije propalo nijedno od njegovih lijepih obećanja koja je dao sluzi svome Mojsiju."},{"v":57,"t":"Neka Jahve, Bog naš, bude s nama kao što je bio s ocima našim i neka nas ne napusti i ne odbaci."},{"v":58,"t":"Neka prikloni naša srca k sebi da bismo hodili svim njegovim putovima i držali njegove zapovijedi, zakone i uredbe koje je dao ocima našim."},{"v":59,"t":"Bile ove moje riječi, koje sam smjerno iznio pred Jahvu, danju i noću nazočne pred Jahvom, Bogom našim, eda bi dan za danom činio pravdu sluzi svomu i pravicu narodu svome Izraelu,"},{"v":60,"t":"ne bi li tako svi narodi zemlje spoznali da je Jahve jedini Bog i da nema drugoga."},{"v":61,"t":"A vaše srce neka bude potpuno odano Jahvi, Bogu našemu, držeći se njegovih zakona i obdržavajući njegove zapovijedi kao danas!”"},{"v":62,"t":"Kralj i sav Izrael s njim prinesu žrtvu Jahvi."},{"v":63,"t":"Kao žrtvu pričesnicu, koju je prikazao Jahvi, Salomon prinese dvadeset i dvije tisuće volova i stotinu i dvadeset tisuća ovaca; time kralj i svi Izraelci posvete Dom Jahvin."},{"v":64,"t":"Toga dana posveti kralj središte predvorja, koje je ispred Doma Jahvina, jer ondje je prinio paljenice, prinosnice i pretiline pričesnica, jer je tučani žrtvenik pred Jahvom bio premalen da primi paljenice, prinosnice, pretiline pričesnica."},{"v":65,"t":"Tu je svečanost u ono vrijeme Salomon slavio sedam dana, sa svim Izraelcima, zborom velikim od Ulaza u Hamat do Potoka Egipatskog, pred Jahvom, Bogom našim."},{"v":66,"t":"Zatim je osmoga dana otpustio ljude; oni su blagosivljali kralja i odlazili svojim kućama, veseli i zadovoljna srca zbog svega dobra što ga je Jahve učinio svome sluzi Davidu i narodu svome Izraelu."}]},"9":{"hr":[{"v":1,"t":"Kad je Salomon dovršio gradnju Doma Jahvina, kraljevskog dvora i svega što je namislio graditi,"},{"v":2,"t":"javi se Jahve i drugi put Salomonu, kao što mu se bio javio u Gibeonu."},{"v":3,"t":"Jahve mu reče: “Uslišio sam molitvu i prošnju koju si mi uputio. Posvetio sam ovaj Dom, koji si sagradio da u njemu prebiva Ime moje dovijeka; moje će oči i srce biti ovdje svagda."},{"v":4,"t":"A ti, ako budeš hodio preda mnom kako je hodio tvoj otac David, u nevinosti srca i pravednosti, postupao u svemu kako sam ti zapovjedio i ako budeš držao moje zakone i moje naredbe,"},{"v":5,"t":"ja ću učvrstiti zauvijek tvoje kraljevsko prijestolje nad Izraelom, kako sam obećao tvome ocu Davidu kad sam rekao: 'Nikada ti neće nestati nasljednika na prijestolju Izraelovu.'"},{"v":6,"t":"Ali ako me ostavite, vi i vaši sinovi, ako ne budete držali mojih zapovijedi i zakona koje sam vam dao, ako se okrenete bogovima i budete im služili i klanjali im se,"},{"v":7,"t":"tada ću istrijebiti Izraela iz zemlje koju sam mu dao; ovaj ću Dom, koji sam posvetio svome Imenu, odbaciti od sebe, i Izrael će biti poruga i podsmijeh svim narodima."},{"v":8,"t":"Ovaj je Dom uzvišen, ali svi koji budu uza nj prolazili bit će zaprepašteni; zviždat će i govoriti: 'Zašto je Jahve tako učinio s ovom zemljom i s ovim Domom?'"},{"v":9,"t":"A reći će im se: 'Jer su ostavili Jahvu, Boga svoga, koji je izveo oce njihove iz Egipta, a priklonili se drugim bogovima, častili ih i služili im, zato je Jahve pustio na njih sva ova zla.'”"},{"v":10,"t":"Poslije dvadeset godina, za kojih je Salomon sagradio obje zgrade, Dom Jahvin i kraljevski dvor,"},{"v":11,"t":"a Hiram, kralj Tira, dobavljao mu drvo cedrovo i čempresovo i zlata koliko je god želio, dade tada kralj Salomon Hiramu dvadeset gradova u zemlji galilejskoj."},{"v":12,"t":"Hiram izađe iz Tira da vidi gradove koje mu je Salomon darovao, ali mu se nisu svidjeli."},{"v":13,"t":"I reče: “Kakvi su to gradovi što si mi ih dao, brate?” I od tada ih zovu “zemlja Kabul” do današnjega dana."},{"v":14,"t":"A Hiram bijaše poslao kralju stotinu i dvadeset zlatnih talenata."},{"v":15,"t":"Ovako je bilo s rabotom koju je kralj Salomon digao da sagradi Dom Jahvin, svoj dvor, Milo i zidove Jeruzalema, Hasor, Megido i Gezer."},{"v":16,"t":"Faraon, kralj Egipta, krenu u vojni pohod, osvoji Gezer, popali i poubija Kanaance koji su ondje živjeli, zatim dade grad u miraz svojoj kćeri, ženi Salomonovoj,"},{"v":17,"t":"a Salomon obnovi Gezer, Bet Horon Donji,"},{"v":18,"t":"Baalat, Tamar u pustinji u zemlji,"},{"v":19,"t":"sve gradove-skladišta koje je Salomon imao, gradove za bojna kola i gradove za konjicu, i sve što je Salomon želio sagraditi u Jeruzalemu, na Libanonu i u svim zemljama koje su mu bile podložne."},{"v":20,"t":"Svim preostalim Amorejcima, Hetitima, Perižanima, Hivijcima i Jebusejcima, koji nisu bili Izraelci,"},{"v":21,"t":"sinovima njihovim koji ostadoše iza njih u zemlji i koje Izraelci nisu zatrli, Salomon nametnu tešku tlaku do današnjega dana."},{"v":22,"t":"Sinove Izraelove nije Salomon pretvarao u robove, nego su mu oni bili vojnici, dvorani, vojskovođe, tridesetnici, zapovjednici njegovih bojnih kola i konjice."},{"v":23,"t":"A evo nadzornika koji su upravljali Salomonovim radovima: njih pet stotina i pedeset koji su zapovijedali puku zaposlenu na radovima."},{"v":24,"t":"Čim je faraonova kći ušla iz Davidova grada u kuću koju joj Salomon bijaše sagradio, tada on podiže Milo."},{"v":25,"t":"Salomon je tri puta u godini prinosio paljenice i pričesnice na žrtveniku koji je podigao Jahvi i palio je kad pred Jahvom. Tako je dovršio Hram."},{"v":26,"t":"Kralj Salomon je sagradio brodovlje u Esjon-Geberu, koji je kralj Elata, na obali Crvenoga mora, u zemlji edomskoj."},{"v":27,"t":"Hiram je poslao na tim lađama svoje sluge, mornare koji su poznavali more, sa slugama Salomonovim."},{"v":28,"t":"Oni otploviše u Ofir, uzeše odande četiri stotine i dvadeset talenata zlata i donesoše ih kralju Salomonu."}]},"10":{"hr":[{"v":1,"t":"Glas koji je u Jahvinu Imenu stekao Salomon dopro je do kraljice od Sabe; zato ona dođe da Salomona iskuša zagonetkama."},{"v":2,"t":"Došla je u Jeruzalem s golemom pratnjom, s devama koje su nosile mirise, nebrojeno zlato i drago kamenje. Došavši k Salomonu, porazgovori se s njim o svemu što joj bijaše na srcu."},{"v":3,"t":"Salomon joj odgovori na sva pitanja; nije mu bilo skriveno ništa da joj ne bi umio objasniti."},{"v":4,"t":"Kad kraljica od Sabe vidje mudrost Salomonovu, dvor koji bijaše sagradio,"},{"v":5,"t":"jela na njegovu stolu, odaje njegove i dvorane, otmjenost njegove posluge i njihova odijela, njegove peharnike i paljenice koje je prinio u Domu Jahvinu, zastade joj dah."},{"v":6,"t":"Tada reče kralju: “Istina je bila što sam u svojoj zemlji čula o tebi i o tvojoj mudrosti."},{"v":7,"t":"Ali nisam htjela vjerovati što se pripovijeda dokle god nisam došla i vidjela na svoje oči; i doista, ni pola mi nije bilo rečeno: ti nadvisuješ u mudrosti i blagostanju slavu o kojoj sam čula."},{"v":8,"t":"Blago tvojim ženama, blago ovim tvojim slugama koji su neprestano pred tobom i slušaju tvoju mudrost!"},{"v":9,"t":"Neka je blagoslovljen Jahve, Bog tvoj, komu si tako omilio da te postavio na prijestolje Izraelaca; zato što Jahve uvijek ljubi Izraela, postavio te kraljem da činiš pravo i pravicu.”"},{"v":10,"t":"Dade tada kralju stotinu i dvadeset zlatnih talenata, mnogo miomirisa i dragulja. Nikad više nije bilo takvih miomirisa kakve je kraljica od Sabe dala kralju Salomonu."},{"v":11,"t":"Pa i Hiramovo brodovlje, koje je donosilo zlato iz Ofira, dovezlo je odande mnogo sandalovine i dragulja."},{"v":12,"t":"Kralj je od sandalovine napravio ograde za Dom Jahvin i za kraljevski dvor, i citre i harfe za pjevače; nikada se više nije dovezlo toliko sandalova drveta niti se vidjelo do danas."},{"v":13,"t":"Kralj Salomon dade kraljici od Sabe što je god zaželjela i zatražila, a povrh toga kraljevski je obdari. Potom ona krenu i sa slugama vrati se u svoju zemlju."},{"v":14,"t":"Zlato što je dolazilo Salomonu svake godine bilo je teško šest stotina šezdeset i šest zlatnih talenata,"},{"v":15,"t":"osim onoga što je dolazilo od trgovaca i prodavača-potukača i od svih arapskih kraljeva i upravitelja zemaljskih."},{"v":16,"t":"Kralj Salomon načini tri stotine velikih štitova od kovanog zlata; za svaki je štit upotrijebio šest stotina zlatnih šekela;"},{"v":17,"t":"i načini trista štitića od kovanog zlata; za svaki je štitić utrošio tri zlatne mine. Pohranio je sve u kuću zvanu Libanonska šuma."},{"v":18,"t":"Kralj je još napravio veliko prijestolje od bjelokosti i obložio ga čistim zlatom."},{"v":19,"t":"Prijestolje je imalo šest stepenica, straga je na njemu bila teleća glava, a s obje strane sjedala bile su ručice, a kraj ručica stajala dva lava."},{"v":20,"t":"Dvanaest je lavova stajalo s obje strane onih šest stepenica. Takvo što nije bilo izrađeno ni u jednom kraljevstvu."},{"v":21,"t":"Sve posude iz kojih je pio kralj Salomon bijahu zlatne, i sve posuđe u kući zvanoj Libanonska šuma bijaše od suhoga zlata; ništa nije bilo od srebra, jer se ono smatralo bezvrijednim u Salomonovo vrijeme."},{"v":22,"t":"Kralj je imao taršiško brodovlje na moru zajedno s Hiramovim brodovljem, i svake treće godine dolazilo je taršiško brodovlje donoseći zlato, srebro i slonovu kost, majmune i paune."},{"v":23,"t":"Tako je kralj Salomon natkrilio sve zemaljske kraljeve bogatstvom i mudrošću."},{"v":24,"t":"Sav je svijet želio vidjeti Salomona i čuti mudrost koju mu je Bog ulio u srce."},{"v":25,"t":"Svatko mu je donosio dar: srebro i zlatno posuđe, haljine, oružje, miomirise, konje i mazge, iz godine u godinu."},{"v":26,"t":"Uz to je Salomon sakupio bojnih kola i konjanika; imao je tisuću i četiri stotine bojnih kola i dvanaest tisuća konja i rasporedio ih je po gradovima bojnih kola i kod kralja u Jeruzalemu."},{"v":27,"t":"Salomon je učinio da u Jeruzalemu bude srebra kao kamenja, a cedrova kao divljih smokava što rastu u Šefeli."},{"v":28,"t":"Salomon je uvozio konje iz Musrija i Koe: kraljevi nabavljači uvozili su ih iz Koe za određenu svotu."},{"v":29,"t":"Kola se dovozila iz Egipta po šest stotina srebrnih šekela; a konj se plaćao po stotinu i pedeset. Tako ih preko nabavljača dobivahu svi kraljevi hetitski i aramejski."}]},"11":{"hr":[{"v":1,"t":"Kralj je Salomon - uz kćer faraonovu - volio mnoge žene tuđinke: Moapke, Amonke, Edomke, Sidonke i Hetitkinje,"},{"v":2,"t":"od svih naroda za koje je Jahve rekao Izraelcima: “Nećete odlaziti k njima i oni neće dolaziti k vama; oni će zacijelo okrenuti vaša srca svojim bogovima.” Njima se priklonio Salomon svojom ljubavlju."},{"v":3,"t":"Imao je sedam stotina kneževskih žena i tri stotine inoča. Njegove su žene zavodile njegovo srce."},{"v":4,"t":"I kada je Salomon ostario, njegove su mu žene okrenule srce prema drugim bogovima, i srce njegovo nije više potpuno pripadalo Jahvi kao što je pripadalo srce njegova oca Davida."},{"v":5,"t":"Salomon je išao za Aštartom, boginjom Sidonaca, i Milkomom, sramotom Amonaca."},{"v":6,"t":"Činio je ono što ne bijaše pravo u očima Jahvinim i nije se sasvim pokoravao Jahvi kao što se pokoravao njegov otac David."},{"v":7,"t":"Tako sagradi Salomon uzvišicu Kemošu, sramoti Moaba, na gori istočno od Jeruzalema, i Milkomu, sramoti Amonaca."},{"v":8,"t":"To učini za sve svoje žene tuđinke, koje su prinosile kad i žrtve svojim bogovima."},{"v":9,"t":"Jahve se razgnjevi na Salomona jer je okrenuo srce svoje od Jahve, Boga Izraelova, koji mu se bio dvaput javio"},{"v":10,"t":"i koji mu je baš tada zabranio štovati druge bogove, ali on nije održao te zapovijedi."},{"v":11,"t":"Tada Jahve reče Salomonu: “Kada je tako s tobom te ne držiš moga Saveza i naredaba koje sam ti dao, ja ću sigurno oduzeti od tebe kraljevstvo i dat ću ga jednom od tvojih slugu."},{"v":12,"t":"Ali neću to učiniti za tvoga života, zbog oca tvojega Davida; uzet ću ga iz ruke tvoga sina."},{"v":13,"t":"Ipak neću od njega uzeti svega kraljevstva: ostavit ću jedno pleme tvome sinu, zbog sluge mojega Davida, zbog Jeruzalema koji izabrah.”"},{"v":14,"t":"Tada diže Jahve protivnika Salomonu: Edomca Hadada, iz kraljevske kuće Edomaca."},{"v":15,"t":"Jer kada je David tukao Edomce i kad je Joab, vojskovođa, otišao da pokopa ubijene i dao pogubiti sve muškarce u Edomu -"},{"v":16,"t":"Joab i sav Izrael ostadoše ondje šest mjeseci dok nisu istrijebili sve muškarce u Edomu -"},{"v":17,"t":"Hadad je utekao u Egipat s Edomcima koji bijahu u službi njegova oca. Hadad je bio tada mladi dječak."},{"v":18,"t":"Otišli su iz Midjana i stigli u Paran. Poveli su sa sobom ljude iz Parana i otišli u Egipat pred faraona, kralja Egipta, koji mu dade kuću, odredi mu hranu i dodijeli zemlje."},{"v":19,"t":"Hadad je stekao veliku milost u faraona, koji mu dade sestru svoje žene, sestru velike kneginje Tafnese."},{"v":20,"t":"Sestra Tafnesina rodi mu sina Genubata, koga Tafnesa odgoji u kraljevskoj palači, i Genubat je ostao u palači među faraonovom djecom."},{"v":21,"t":"Kada je Hadad doznao u Egiptu da je David počinuo kod svojih otaca i da je vojskovođa Joab umro, reče faraonu: “Dopusti mi da odem u svoju zemlju!”"},{"v":22,"t":"Faraon mu reče: “Što ti nedostaje u mene te želiš poći u svoju zemlju?” A on mu odgovori: “Ništa, ali me pusti da odem!” [25b] To je bilo zlo što ga je učinio Hadad: mrzio je Izraela i vladao je Edomom."},{"v":23,"t":"Bog je protiv Salomona podigao protivnika mu Rezona, sina Elijadova, koji je pobjegao od svoga gospodara Hadadezera, kralja sopskoga;"},{"v":24,"t":"Rezon je skupio ljude oko sebe i postao im četovođa kada ih David ubijaše. Rezon zauze Damask, ondje se nastani i zavlada Damaskom."},{"v":25,"t":"[25a] On je bio protivnik Izraelov za života Salomonova."},{"v":26,"t":"Jeroboam bijaše sin Efraćanina Nebata, iz Sareda, a majka mu bijaše udovica imenom Serva. On je bio u službi Salomonovoj i podigao je ruku protiv kralja."},{"v":27,"t":"Evo razloga njegove pobune. Salomon je gradio Milo da zatrpa kosinu u gradu Davida, oca svoga."},{"v":28,"t":"Taj Jeroboam bijaše valjan čovjek; Salomon opazi kako se mladi čovjek prihvaća posla i postavi ga nad svom rabotom kuće Josipove."},{"v":29,"t":"Tada se dogodi te Jeroboam ode iz Jeruzalema, i na putu ga susrete prorok Ahija iz Šila, ogrnut novim plaštem; bijahu sami njih dvojica u polju."},{"v":30,"t":"Ahija uze novi plašt koji je imao na sebi i razdrije ga na dvanaest komada."},{"v":31,"t":"I reče Jeroboamu: “Uzmi sebi deset komada, jer ovako govori Jahve, Bog Izraelov: 'Evo ću istrgnuti kraljevstvo iz ruke Salomonove i dat ću tebi deset plemena."},{"v":32,"t":"On će imati jedno pleme, zbog sluge mojega Davida i Jeruzalema, grada koji sam izabrao između svih plemena Izraelovih."},{"v":33,"t":"To je zato što me ostavio i poklonio se Aštarti, boginji Sidonaca, Kemošu, bogu moapskom, i Milkomu, bogu Amonaca, i ne hodi više mojim putovima; ne čini što je pravo u mojim očima, niti izvršava moje zakone i naredbe kao što je činio njegov otac David."},{"v":34,"t":"Ali mu neću iz ruke uzeti sve kraljevstvo, jer sam ga postavio knezom za sveg njegova života, zbog sluge svoga Davida, koga sam izabrao i koji je držao moje zapovijedi i moje zakone."},{"v":35,"t":"Ali ću uzeti kraljevstvo iz ruke njegova sina i tebi ću ga dati, to jest deset plemena."},{"v":36,"t":"A njegovu ću sinu ostaviti jedno pleme da moj sluga David ima uvijek svjetiljku preda mnom u Jeruzalemu, gradu koji sam izabrao sebi da u njemu stoluje Ime moje."},{"v":37,"t":"Tebe ću uzeti da kraljuješ nad svim što budeš želio i da budeš kralj nad Izraelom."},{"v":38,"t":"Ako budeš poslušao sve što ti zapovjedim i stupao budeš putovima mojim te činio što je pravedno u očima mojim držeći moje zakone i zapovijedi moje, kako je to činio moj sluga David, tada ću ja biti s tobom i sagradit ću ti trajan dom, kao što sam sagradio Davidu, i dat ću ti Izraela."},{"v":39,"t":"Ponizit ću potomke Davidove; ali ne zauvijek.'”"},{"v":40,"t":"Salomon je zato tražio da ubije Jeroboama, ali on pobježe u Egipat k Šišaku i ostade u Egiptu do smrti Salomonove."},{"v":41,"t":"Ostala povijest Salomonova, sve što je učinio i njegova mudrost, zar nije zapisana u knjizi Povijesti Salomonove?"},{"v":42,"t":"A kraljevaše Salomon u Jeruzalemu nad svim Izraelom četrdeset godina."},{"v":43,"t":"Onda počinu Salomon kod otaca svojih i bi sahranjen u Davidovu gradu, a njegov sin Roboam zakralji se namjesto njega."}]},"12":{"hr":[{"v":1,"t":"Roboam ode u Šekem, jer su u Šekem došli svi Izraelci da ga zakralje."},{"v":2,"t":"Čim to ču Nebatov sin Jeroboam - koji još bijaše u Egiptu, kamo je pobjegao pred kraljem Salomonom - vrati se iz Egipta, jer"},{"v":3,"t":"bijahu poslali po nj i dozvali ga. Kad dođoše Jeroboam i sav zbor Izraelov, rekoše Roboamu:"},{"v":4,"t":"“Tvoj nam je otac nametnuo teški jaram. Ti nam sada olakšaj tešku službu svoga oca, teški jaram koji metnu na nas, pa ćemo ti služiti!”"},{"v":5,"t":"A on im odgovori: “Za tri dana dođite opet k meni.” I narod ode."},{"v":6,"t":"Tada se kralj Roboam posavjetova sa starcima koji su služili njegovu ocu Salomonu dok je bio živ i upita ih: “Što savjetujete da odgovorim ovome narodu?”"},{"v":7,"t":"Oni mu odgovoriše: “Ako danas udovoljiš tim ljudima, budeš im blagonaklon i odgovoriš im lijepim riječima, oni će ti uvijek ostati sluge.”"},{"v":8,"t":"Ali on odbaci savjet što mu ga dadoše starci i posavjetova se s mladićima koji su odrasli s njim i bili mu u službi."},{"v":9,"t":"Upita ih: “Što savjetujete da odgovorim ovome narodu koji mi reče: 'Olakšaj jaram što nam ga nametnu tvoj otac?'”"},{"v":10,"t":"Mladići koji bijahu s njime odrasli odgovoriše mu: “Narodu koji ti reče: 'Tvoj nam je otac nametnuo jaram, a ti nam ga olakšaj', uzvrati ovako: 'Moj je mali prst deblji od bedara moga oca!"},{"v":11,"t":"Eto, moj vam je otac nametnuo teški jaram, a ja ću još otežati vaš jaram; moj vas je otac šibao bičevima, a ja ću vas šibati bičevima sa željeznim štipavcima.'”"},{"v":12,"t":"A treći dan dođe sav narod k Roboamu, kako im bijaše zapovjedio kralj rekavši im: “Vratite se k meni trećega dana.”"},{"v":13,"t":"Kralj im oštro odgovori, odbacivši savjet koji mu dadoše stariji."},{"v":14,"t":"I reče im po savjetu mladih: “Moj je otac otežao vaš jaram, a ja ću još dodati na nj; moj vas je otac šibao bičevima, a ja ću vas šibati bičevima sa željeznim štipavcima.”"},{"v":15,"t":"Kralj dakle ne htjede poslušati naroda, jer tako upriliči Jahve da se ispuni riječ što je preko Ahije iz Šila kaza Nebatovu sinu Jeroboamu."},{"v":16,"t":"Kad Izraelci vidješe gdje se kralj oglušio, odgovori mu narod: “Kakav dio mi imamo s Davidom? Mi nemamo baštine s Jišajevim sinom. U šatore, Izraele! A sad se, Davide, brini za svoj dom!” I sav Izrael ode pod svoje šatore."},{"v":17,"t":"Roboam zavlada samo nad Izraelovim sinovima koji su živjeli po judejskim gradovima."},{"v":18,"t":"Potom kralj Roboam posla Adorama, nadstojnika za tlaku, ali ga Izraelci kamenovaše i on umrije; a kralj se Roboam brže-bolje pope na kola i pobježe u Jeruzalem."},{"v":19,"t":"Tako se Izrael odijelio od doma Davidova sve do danas."},{"v":20,"t":"Kada su Izraelci doznali da se vratio Jeroboam, pozvaše ga u zajednicu i postaviše ga kraljem nad svim Izraelom. Uz kuću Davidovu nije pristajao nitko, osim samoga plemena Judina."},{"v":21,"t":"Došavši u Jeruzalem, Roboam skupi sav dom Judin i pleme Benjaminovo, sto i osamdeset tisuća vrsnih ratnika, da udare na dom Izraelov i da vrate kraljevstvo Roboamu, sinu Salomonovu."},{"v":22,"t":"Ali dođe Jahvina riječ Božjem čovjeku Šemaji:"},{"v":23,"t":"“Kaži Salomonovu sinu Roboamu, judejskom kralju, i svem domu Judinu i Benjaminovu i ostalom narodu:"},{"v":24,"t":"Ovako veli Jahve: 'Ne idite se tući s braćom, djecom Izraelovom! Neka se svatko vrati svojoj kući, jer je ovo poteklo od mene.'” I oni poslušaše riječ Jahvinu i vratiše se kako im reče Jahve."},{"v":25,"t":"Jeroboam utvrdi Šekem u Efrajimovoj gori i ondje se nastani. Poslije izađe odatle i utvrdi Penuel."},{"v":26,"t":"Jeroboam reče u svom srcu: “Sad bi se kraljevstvo moglo vratiti domu Davidovu."},{"v":27,"t":"Ako ovaj narod bude nastavio uzlaziti u Dom Jahvin u Jeruzalemu da prinosi žrtve, srce će se naroda vratiti svome gospodaru, Roboamu, kralju judejskome, i mene će ubiti.”"},{"v":28,"t":"Pošto se kralj posavjetovao, načini dva zlatna teleta i reče narodu: “Dosta ste uzlazili u Jeruzalem! Evo, Izraele, tvoga boga koji te izveo iz zemlje egipatske.”"},{"v":29,"t":"Zatim postavi jedno tele u Betelu, a drugo smjesti u Dan."},{"v":30,"t":"To je bila prigoda za grijeh: narod je odlazio jednome u Betel i drugome u Dan."},{"v":31,"t":"I podiže Jeroboam hram na uzvišicama i postavi iz puka svećenike koji nisu bili sinovi Levijevi."},{"v":32,"t":"Zatim je Jeroboam uveo blagdan u osmom mjesecu, petnaestoga dana tog mjeseca, kao što je blagdan koji se slavi u Judeji, i uzađe k žrtveniku. Tako je učinio u Betelu, žrtvujući teocima koje je načinio. U Betelu je postavio i svećenike uzvišica što ih bijaše podigao."},{"v":33,"t":"I uzađe k žrtveniku koji je načinio, petnaestoga dana osmog mjeseca, mjeseca koji je sam izabrao; i ustanovi blagdan za Izraelce i uzađe k žrtveniku da prinese kad."}]},"13":{"hr":[{"v":1,"t":"A neki čovjek Božji dođe na riječ Jahvinu iz Judeje u Betel kada Jeroboam stajaše pred žrtvenikom da prinese kad."},{"v":2,"t":"I po Jahvinoj zapovijedi povika onaj prema žrtveniku: “Žrtveniče, žrtveniče! Ovako veli Jahve: 'Evo će se roditi u kući Davidovoj sin po imenu Jošija. On će na tebi žrtvovati svećenike uzvišica, te koji na tebi prinose kad, i on će na tebi spaliti ljudske kosti!'”"},{"v":3,"t":"U isto im vrijeme dade znak: “Ovo je znak da je Jahve govorio: gle, žrtvenik će se raspuknuti i prosut će se pepeo što je na njemu.”"},{"v":4,"t":"Kada je kralj čuo što je čovjek Božji rekao protiv žrtvenika u Betelu, pruži ruku odande od žrtvenika i reče: “Uhvatite ga!” Ali se osušila ruka koju je ispružio prema čovjeku i nije je mogao vratiti k sebi."},{"v":5,"t":"Žrtvenik se raspuknuo i pepeo se prosuo sa žrtvenika, prema znaku što ga je dao čovjek Božji po naredbi Jahvinoj."},{"v":6,"t":"Kralj progovori i reče čovjeku Božjem: “Umilostivi Jahvu, Boga svoga, da bih mogao vratiti ruku k sebi.” Božji čovjek umilostivi Jahvu i ruka se kraljeva vrati k njemu i bila je kao prije."},{"v":7,"t":"Kralj onda reče čovjeku Božjem: “Hodi sa mnom kući da se okrijepiš. I dat ću ti dar.”"},{"v":8,"t":"Ali čovjek Božji odgovori kralju: “Da mi dadeš polovinu svoje kuće, ne bih pošao s tobom. Ni jeo ni pio ne bih na ovom mjestu,"},{"v":9,"t":"jer mi je ovako zapovjeđeno riječju Jahvinom: 'Ne jedi kruha i ne pij vode, niti se vraćaj istim putem kojim si došao.'”"},{"v":10,"t":"I otišao je drugim putem, nije se vraćao putem kojim je došao u Betel."},{"v":11,"t":"A u Betelu živio star prorok. Došli njemu njegovi sinovi te mu pripovjedili sve što je onoga dana učinio čovjek Božji u Betelu; i riječi što ih je onaj kazao kralju pripovjediše sinovi ocu."},{"v":12,"t":"A on ih upita: “Kojim je putem otišao?” Sinovi pokazaše put kojim je otišao čovjek Božji što bijaše došao iz Judeje."},{"v":13,"t":"Prorok će nato sinovima: “Osamarite mi magarca!” I osamariše mu magarca, a on uzjaha."},{"v":14,"t":"Krenuo je za čovjekom Božjim i našao ga gdje sjedi pod hrastom; i upita ga: “Jesi li ti čovjek Božji koji je došao iz Judeje?” A on mu odgovori: “Jesam.”"},{"v":15,"t":"Prorok mu reče: “Hodi sa mnom mome domu da štogod pojedeš.”"},{"v":16,"t":"Ali on odgovori: “Ne smijem se vratiti s tobom, niti smijem jesti kruha ni piti vode na ovome mjestu,"},{"v":17,"t":"jer mi je Jahvinom riječju naređeno ovo: 'Ne jedi ondje kruha, ne pij vode, niti se vraćaj putem kojim si onamo pošao'.”"},{"v":18,"t":"Nato će mu onaj: “I ja sam prorok kao i ti, i anđeo mi je riječju Jahvinom rekao: 'Povedi ga sa sobom kući da jede kruha i pije vode.'” Slagao mu je."},{"v":19,"t":"Božji čovjek vrati se s njim, u njegovoj je kući jeo kruha i pio vode."},{"v":20,"t":"Dok su sjedili za stolom, dođe riječ Jahvina proroku koji ga je natrag doveo"},{"v":21,"t":"i povika on čovjeku Božjem koji je došao iz Judeje: “Ovako veli Jahve: zato što nisi poslušao zapovijedi Jahvine i nisi držao naredbe koju ti je dao Jahve, Bog tvoj,"},{"v":22,"t":"nego si se vratio, jeo kruha i pio vode na mjestu gdje sam ti rekao da ne jedeš kruha i ne piješ vode, zato tijelo tvoje neće leći u grob otaca tvojih.”"},{"v":23,"t":"Pošto se onaj koga bijaše doveo najeo kruha i napio vode, osedla mu magarca."},{"v":24,"t":"I ode onaj. A na putu ga zaskoči lav i usmrti ga. I tako je mrtvo tijelo ležalo ispruženo na putu, magarac stajao kraj njega, a i lav stajaše kraj tijela."},{"v":25,"t":"Ljudi prolazeći vidješe mrtvo tijelo ispruženo na putu i lava gdje stoji kraj njega; i odoše i javiše to u gradu gdje je živio stari prorok."},{"v":26,"t":"Kad je to čuo prorok koji bijaše onoga vratio s puta, reče: “To je čovjek Božji koji se usprotivio riječi Jahvinoj! I Jahve ga je predao lavu, koji ga je napao i ubio, prema riječi koju je Jahve rekao.”"},{"v":27,"t":"I reče svojim sinovima: “Osamarite mi magarca!” I oni mu ga osamariše."},{"v":28,"t":"Ode on i nađe mrtvo tijelo bačeno na putu i magarca i lava gdje stoje pokraj tijela: lav nije požderao tijelo niti je rastrgao magarca."},{"v":29,"t":"Tada prorok podiže mrtvo tijelo čovjeka Božjeg i prebaci ga na magarca; i vrati se u grad gdje je živio da mrtvoga ožali i pokopa."},{"v":30,"t":"Položio je mrtvo tijelo u svoju grobnicu i jecao je nad njim: “Jao, brate moj!”"},{"v":31,"t":"A kad ga je pokopao, reče svojim sinovima: “Poslije moje smrti sahranite me u istu grobnicu gdje je pokopan čovjek Božji; stavite moje kosti kraj njegovih."},{"v":32,"t":"Jer će se sigurno ispuniti riječ koju je po zapovijedi Jahvinoj objavio protiv žrtvenika u Betelu i protiv svih svetišta na uzvišicama u gradovima Samarije.”"},{"v":33,"t":"Ni poslije ovoga događaja ne obrati se Jeroboam za svoga zlog puta, nego je i dalje priproste ljude postavljao za svećenike na uzvišicama: tko je želio, davao mu je darove da postane svećenik uzvišica."},{"v":34,"t":"Takvim je postupkom padala u grijeh kuća Jeroboamova, rušila se i nestajala s lica zemlje."}]},"14":{"hr":[{"v":1,"t":"U ono se vrijeme razbolje Abija, sin Jeroboamov,"},{"v":2,"t":"i Jeroboam reče svojoj ženi: “Ustani i preobuci se da te ne bi prepoznali da si žena Jeroboamova; i idi u Šilo. Ondje je prorok Ahija: onaj koji mi je prorokovao da ću biti kraljem ovoga naroda."},{"v":3,"t":"I ponesi deset hljebova, kolača i posudu meda i otiđi k njemu! On će ti reći što će biti s dječakom.”"},{"v":4,"t":"I učini tako žena Jeroboamova: ustade, ode u Šilo i uđe u kuću Ahijinu. A on nije više vidio, oslabile mu oči od duboke starosti."},{"v":5,"t":"Ali mu je Jahve rekao: “Evo dolazi žena Jeroboamova da od tebe traži savjeta za svoga sina jer je bolestan; a ti ćeš joj reći tako i tako. Kad bude ulazila, pretvarat će se kao da je druga.”"},{"v":6,"t":"Kad Ahija ču šum njenih koraka na vratima, reče joj: “Uđi, ženo Jeroboamova! Što se pretvaraš da si druga, kad imam tešku vijest za tebe?"},{"v":7,"t":"Idi, reci Jeroboamu: 'Ovako kaže Jahve, Bog Izraelov: Podigao sam te isred naroda i učinio sam te knezom nad mojim narodom Izraelom,"},{"v":8,"t":"istrgnuo sam kraljevstvo iz kuće Davidove i dao ga tebi. Ali ti nisi bio kao moj sluga David, koji je držao moje zapovijedi i koji me slijedio svim srcem svojim i činio samo ono što je pravedno u mojim očima."},{"v":9,"t":"Ti si radio kudikamo gore od svojih prethodnika, otišao si i načinio sebi druge bogove, salio si im likove da me dražiš, mene si bacio za leđa."},{"v":10,"t":"Zato, evo, puštam zlo na kuću Jeroboamovu, istrijebit ću iz obitelji Jeroboamove sve što mokri uza zid, robove i slobodnjake u Izraelu; ja ću netragom pomesti kuću Jeroboamovu kao što se mete nečist, da ga ništa ne ostane."},{"v":11,"t":"One koji iz Jeroboamove obitelji umru u gradu, proždrijet će psi, a one koji umru u polju, pojest će ptice nebeske.' - Eto tako je Jahve rekao."},{"v":12,"t":"A ti ustani i pođi svome domu: tek što nogama stupiš u grad, dječak će umrijeti."},{"v":13,"t":"Sav će ga Izrael oplakati i pokopat će ga. On će biti jedini iz obitelji Jeroboamove položen u grob, jer se jedino na njemu našlo nešto što se u kući Jeroboamovoj svidjelo Jahvi, Bogu Izraelovu."},{"v":14,"t":"Jahve će sebi postaviti kralja nad Izraelom i taj će istrijebiti kuću Jeroboamovu. Evo dana! Što? Čak i trenutka!"},{"v":15,"t":"Jahve će udariti Izraela te će se njihati kao trska u vodi. Iščupat će Izraela iz ove dobre zemlje koju je dao njihovim ocima i rasijat će ih s onu stranu Rijeke, jer su načinili sebi ašere koje srde Jahvu."},{"v":16,"t":"Odbacit će Izraela kao smeće, zbog grijeha što ih je učinio Jeroboam i na koje je navodio Izraela.”"},{"v":17,"t":"Žena Jeroboamova ustade i ode. Stigla je u Tirsu, a kad je prelazila kućni prag, dječak bijaše mrtav."},{"v":18,"t":"Pokopali su ga i sav ga je Izrael oplakao prema riječi koju je Jahve rekao po sluzi svome proroku Ahiji."},{"v":19,"t":"Ostala povijest Jeroboamova, kako je ratovao i kraljevao, to je zapisano u knjizi Ljetopisa kraljeva izraelskih."},{"v":20,"t":"Jeroboamovo kraljevanje trajalo je dvadeset i dvije godine, zatim je Jeroboam počinuo kraj otaca svojih, a sin mu Nadab zakraljio se mjesto njega."},{"v":21,"t":"Roboam, sin Salomonov, bio je kralj Judejaca; bijaše mu četrdeset i jedna godina kad je postao kraljem, a sedamnaest je godina kraljevao u Jeruzalemu, u gradu koji Jahve izabra između svih izraelskih plemena da ondje postavi svoje Ime. Majka mu se zvala Naama, a bila je Amonka."},{"v":22,"t":"I Juda učini zlo u očima Jahvinim. Grijesima koje su počinili razjarili su ga više od svega što su učinili njihovi oci."},{"v":23,"t":"Jer su i oni podigli uzvišice, stupove i ašere na svakom brežuljku i pod svakim zelenim drvetom."},{"v":24,"t":"Bilo je čak posvećenih bludnica u zemlji. Oponašao je sve grozote naroda što ih je Jahve otjerao ispred sinova Izraelovih."},{"v":25,"t":"Pete godine Roboamova kraljevanja egipatski kralj Šišak navali na Jeruzalem."},{"v":26,"t":"Opljačka sve blago iz Doma Jahvina i riznicu kraljevskog dvora; sve je uzeo; uze i sve zlatne štitove što ih bijaše napravio Salomon."},{"v":27,"t":"Namjesto njih kralj Roboam napravi tučane štitove i povjeri ih zapovjednicima straže koja je čuvala vrata kraljevskog dvora."},{"v":28,"t":"Kad je god kralj išao u Jahvin Dom, stražari su ih uzimali, a poslije ih vraćali u stražaru."},{"v":29,"t":"Ostala povijest Roboamova, sve što je učinio, zar nije zapisano u knjizi Ljetopisa kraljeva judejskih?"},{"v":30,"t":"Za sve vrijeme bio je rat između Roboama i Jeroboama."},{"v":31,"t":"Roboam je počinuo sa svojim ocima i bi sahranjen sa svojim ocima u Davidovu gradu. Majka mu se zvala Naama, a bila je Amonka. Na njegovo se mjesto zakraljio sin mu Abijam."}]},"15":{"hr":[{"v":1,"t":"Osamnaeste godine kraljevanja Jeroboama, sina Nebatova, zakraljio se Abijam u Judeji."},{"v":2,"t":"Tri je godine kraljevao u Jeruzalemu; njegova se majka zvala Maaka, a bila je kći Abšalomova."},{"v":3,"t":"On je hodio u svim grijesima što ih je njegov otac činio prije njega, i njegovo srce nije bilo potpuno odano Jahvi, Bogu svome, kao srce njegova praoca Davida."},{"v":4,"t":"Ipak, zbog Davida, dao mu je Jahve, Bog njegov, svjetiljku u Jeruzalemu, podigavši sinove njegove poslije njega i sačuvavši Jeruzalem."},{"v":5,"t":"Jer je David činio sve što je pravo u očima Jahvinim i za svega svoga života nije odstupio ni od čega što mu je zapovjedio, osim onog što je učinio Uriji Hetitu."},{"v":6,"t":"#"},{"v":7,"t":"Ostala povijest Abijamova, sve što je učinio, zar to nije zapisano u knjizi Ljetopisa kraljeva judejskih? A bijaše rat između Abijama i Jeroboama."},{"v":8,"t":"Potom je Abijam počinuo sa svojim ocima. Sahraniše ga u Davidovu gradu; na njegovo se mjesto zakralji sin mu Asa."},{"v":9,"t":"Dvadesete godine Jeroboamova kraljevanja nad Izraelom postade Asa kraljem Judeje."},{"v":10,"t":"Kraljevao je četrdeset i jednu godinu u Jeruzalemu; njegova se baka zvala Maaka, a bila je kći Abšalomova."},{"v":11,"t":"Asa je činio što je pravo u očima Jahvinim, kao i njegov praotac David."},{"v":12,"t":"Protjerao je iz zemlje posvećene bludnice i uklonio sve idole koje njegovi oci bijahu načinili."},{"v":13,"t":"Sam je uklonio svoju baku s dostojanstva velike kneginje, jer bijaše načinila gada Ašeri. Asa je sasjekao njezina gada i spalio ga u potoku Kidronu."},{"v":14,"t":"Ali uzvišice nisu bile uklonjene; ipak je Asino srce bilo privrženo Jahvi svega njegova života."},{"v":15,"t":"Unio je u Dom Jahvin posvećene darove svoga oca i svoje: srebro, zlato i posuđe."},{"v":16,"t":"Bio je rat između Ase i Baše, kralja izraelskoga, u sve njihove dane."},{"v":17,"t":"Izraelski kralj Baša navali na Judeju i stade utvrđivati Ramu da spriječi svako kretanje judejskom kralju Asi."},{"v":18,"t":"Asa tada uze srebra i zlata koje je preostalo u riznicama Doma Jahvina i u riznicama kraljevskog dvora i dade ga svojim slugama te ih posla Ben-Hadadu, sinu Tabrimonovu, sinu Hezjonovu, aramejskom kralju, koji je stolovao u Damasku, i poruči mu:"},{"v":19,"t":"“Neka bude savez između mene i tebe, između moga i tvoga oca; evo, šaljem ti na dar srebra i zlata: hajde, raskini savez s izraelskim kraljem Bašom da bi otišao od mene.”"},{"v":20,"t":"Ben-Hadad posluša kralja Asu i posla svoje vojskovođe na izraelske gradove te oni pokoriše Ijon, Dan, Abel Bet-Maaku, sav Kineret i svu zemlju Naftali."},{"v":21,"t":"A kada to Baša dozna, presta utvrđivati Ramu i vrati se u Tirsu."},{"v":22,"t":"Kralj Asa sazva sve Judejce, bez izuzetka, i oni odnesoše kamenje i drvo kojima je Baša utvrđivao Ramu, i kralj Asa utvrdi time Gebu Benjaminovu i Mispu."},{"v":23,"t":"Ostala povijest Asina, sve njegove pobjede i sve što je učinio i gradovi koje je utvrdio, zar to nije zapisano u knjizi Ljetopisa kraljeva judejskih? A u starosti bolovao je od nogu."},{"v":24,"t":"Asa je počinuo sa svojim ocima i sahranjen je sa svojim ocima u gradu Davida, svoga praoca. Njegov sin Jošafat zakralji se mjesto njega."},{"v":25,"t":"Nadab, sin Jeroboamov, postade kraljem Izraela druge godine Asina kraljevanja Judejom i vladao je dvije godine Izraelom."},{"v":26,"t":"Činio je zlo u očima Jahvinim. Hodio je putem svoga oca i oponašao njegov grijeh na koji je navodio Izraela."},{"v":27,"t":"Baša, sin Ahijin, iz kuće Jisakarove, uroti se protiv njega i ubi ga u Gibetonu, koji pripada Filistejcima i koji su opsjedali Nadab i sav Izrael."},{"v":28,"t":"Baša ga ubi treće godine Asina kraljevanja Judejom i zavlada mjesto njega."},{"v":29,"t":"Kad je postao kraljem, pobi svu kuću Jeroboamovu i ne poštedi nikoga od Jeroboamovih dokle sve ne istrijebi po riječi koju je Jahve rekao preko sluge svoga Ahije iz Šila."},{"v":30,"t":"Zbog grijeha što ih je učinio i na koje je naveo Izraela i zbog gnjeva kojim je raspalio Jahvu, Boga Izraelova."},{"v":31,"t":"Ostala povijest Nadabova, i sve što je učinio, zar to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":32,"t":"Između Ase i Izraelova kralja Baše vladao je rat u sve njihove dane."},{"v":33,"t":"Treće godine Asina kraljevanja Judejom postade Baša, sin Ahijin, kraljem nad svim Izraelom u Tirsi i vladao je dvadeset i četiri godine."},{"v":34,"t":"Činio je zlo u očima Jahvinim i hodio je putem Jeroboama i njegovih grijeha kojima je zavodio Izraelce."}]},"16":{"hr":[{"v":1,"t":"Tada bi upućena riječ Jahvina Jehuu, sinu Hananijevu, protiv Baše:"},{"v":2,"t":"“Iz praha sam te podigao i postavio knezom nad mojim narodom Izraelom, ali si ti krenuo Jeroboamovim putem i navodiš narod moj Izrael na grijehe te me razjaruješ njihovim grijesima;"},{"v":3,"t":"zato ću netragom pomesti Bašu i kuću njegovu: učinit ću s tvojom kućom kao i s kućom Jeroboama, sina Nebatova."},{"v":4,"t":"Tko iz obitelji Bašine umre u gradu, pojest će ga psi, a tko im umre u polju, pojest će ga ptice nebeske.”"},{"v":5,"t":"Ostala povijest Bašina, što je učinio, njegova djela, zar sve to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":6,"t":"Baša je počinuo sa svojim ocima i sahranjen je u Tirsi. Sin njegov Ela zakraljio se mjesto njega."},{"v":7,"t":"Ali riječ Jahvina po Jehuu proroku, sinu Hananijevu, nije bila upravljena protiv Baše i njegove kuće samo zbog toga što je činio zlo u očima Jahve i ljutio ga djelima svojih ruku te bio kao i kuća Jeroboamova nego i zbog toga što je i nju istrijebio."},{"v":8,"t":"Dvadeset i šeste godine kraljevanja Ase u Judeji postade Ela, sin Bašin, kraljem Izraela u Tirsi; vladao je svega dvije godine."},{"v":9,"t":"Njegov dvoranin Zimri, zapovjednik polovine bojnih kola, uroti se protiv njega. Kad je bio u Tirsi, opio se u kući Arse, upravitelja dvora u Tirsi."},{"v":10,"t":"Tada provali Zimri, udari na njega i ubi ga, dvadeset i sedme godine Asina kraljevanja Judejom, te zavlada mjesto njega."},{"v":11,"t":"Čim je zavladao i sjeo na prijestolje, poubija svu obitelj Bašinu; nije mu poštedio ni što uza zid mokri, ni njegovih rođaka ni prijatelja."},{"v":12,"t":"Tako Zimri iskorijeni svu kuću Bašinu po riječi koju je Jahve rekao protiv Baše preko sluge svoga proroka Jehua,"},{"v":13,"t":"zbog sviju grijeha što su ih činili Baša i sin mu Ela i tako zavodili Izraela, srdeći Jahvu, Boga Izraelova, svojim krivim bogovima."},{"v":14,"t":"Ostala povijest Elina, sve što je učinio, zar to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":15,"t":"Dvadeset i sedme godine Asina kraljevanja Judejom postade Zimri kraljem u Tirsi i vladao je sedam dana. Narod je tada opsjedao Gibeton, koji je pripadao Filistejcima."},{"v":16,"t":"Kad je utaboreni narod čuo da se Zimri pobunio i ubio kralja, sav Izrael istoga dana u taboru proglasi kraljem nad Izraelom zapovjednika vojske Omrija."},{"v":17,"t":"Zatim Omri i sav Izrael s njime odoše od Gibetona i opsjedoše Tirsu."},{"v":18,"t":"Kad je Zimri vidio da će grad biti osvojen, uđe u utvrdu kraljevskoga dvora, zapali nad sobom kraljevski dvor i tako pogibe."},{"v":19,"t":"To je bilo zbog grijeha koje je počinio radeći što je zlo u očima Jahvinim i hodeći putem Jeroboama i njegovih grijeha kojima je zavodio Izraela."},{"v":20,"t":"Ostala povijest Zimrijeva i njegova urota koju je skovao, zar sve to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":21,"t":"Tada se Izraelov narod razdijelio: polovica se odlučila za Tibnija, sina Ginatova, da ga učini kraljem, a druga polovica za Omrija."},{"v":22,"t":"Ali pristaše Omrijeve nadjačaše pristaše Tibnija, sina Ginatova, pa kad Tibni umrije, postade Omri kraljem."},{"v":23,"t":"Trideset i prve godine Asina kraljevanja Judejom postade Omri kraljem Izraela za dvanaest godina. U Tirsi je kraljevao šest godina."},{"v":24,"t":"Tada kupi od Šemera za dva talenta srebra brdo Samariju; sagradi grad koji po imenu Šemera, vlasnika brijega, nazva Samarija."},{"v":25,"t":"Ali je Omri činio zlo u očima Jahvinim i bio je gori od svojih prethodnika."},{"v":26,"t":"U svemu je slijedio Jeroboama, sina Nebatova, i njegove grijehe kojima je zavodio Izraela i srdio Jahvu, Boga Izraelova, svojim lažnim bogovima."},{"v":27,"t":"Ostala povijest Omrijeva, sve što je učinio, njegovi pothvati koje je izveo, zar to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":28,"t":"Omri počinu sa svojim ocima i sahranjen je u Samariji. Njegov sin Ahab postade kraljem mjesto njega."},{"v":29,"t":"Ahab, sin Omrijev, postade izraelskim kraljem u trideset i osmoj godini Asina kraljevanja Judejom i vladao je dvadeset i dvije godine nad Izraelom u Samariji."},{"v":30,"t":"Ahab, sin Omrijev, činio je u očima Jahvinim više zla od svih svojih prethodnika."},{"v":31,"t":"I malo mu bijaše što je hodio u grijesima Jeroboama, sina Nebatova, nego se još oženi Izebelom, kćerju Etbaala, kralja sidonskog, i poče služiti Baalu i klanjati mu se;"},{"v":32,"t":"Baalu podiže žrtvenik u Baalovu hramu što ga bijaše sagradio u Samariji."},{"v":33,"t":"Ahab je podigao i Ašeru i učinio druga zlodjela i razljutio Jahvu, Boga Izraelova, više od svih kraljeva izraelskih koji bijahu prije njega."},{"v":34,"t":"Za njegova je vremena Hiel iz Betela sagradio Jerihon; uz žrtvu svoga prvorođenca Abirama podigao je temelje, a uz žrtvu svoga mezimca Seguba postavio je gradska vrata, po riječi koju je Jahve rekao po svome sluzi Jošui, sinu Nunovu."}]},"17":{"hr":[{"v":1,"t":"Ilija Tišbijac, iz Tišbe Gileadske, reče Ahabu: “Živoga mi Jahve, Boga Izraelova, komu služim, neće ovih godina biti ni rose ni kiše, osim na moju zapovijed.”"},{"v":2,"t":"Upućena mu je riječ Jahvina ovako:"},{"v":3,"t":"“Idi odavde i kreni na istok i sakrij se na potoku Keritu, koji je nasuprot Jordanu."},{"v":4,"t":"Pit ćeš iz potoka, a gavranima sam zapovjedio da te ondje hrane.”"},{"v":5,"t":"Ode on i učini po riječi Jahvinoj i nastani se na potoku Keritu, nasuprot Jordanu."},{"v":6,"t":"Gavrani su mu jutrom donosili kruha, a večerom mesa; iz potoka je pio."},{"v":7,"t":"Ali poslije nekog vremena presuši potok, jer nije bilo kiše u svoj zemlji."},{"v":8,"t":"Tada Iliji dođe riječ Jahvina:"},{"v":9,"t":"“Ustani, idi u Sarfatu Sidonsku i ondje ostani. Evo, ondje sam zapovjedio jednoj udovici da te hrani.”"},{"v":10,"t":"Ustade on i krenu u Sarfatu. Kada je stigao do gradskih vrata, neka je udovica onuda skupljala drva; on joj se obrati i reče: “Donesi mi malo vode u vrču da pijem!”"},{"v":11,"t":"Kad je pošla da donese, on viknu za njom i reče joj: “Donesi mi i malo kruha u ruci!”"},{"v":12,"t":"Ona odgovori: “Živoga mi Jahve, tvoga Boga, ja nemam pečena kruha, nemam do pregršti brašna u ćupu i malo ulja u vrču. I evo kupim drva, pa ću otići i ono pripremiti sebi i svome sinu da pojedemo i da umremo.”"},{"v":13,"t":"Ali joj Ilija reče: “Ništa se ne boj. Idi i uradi kako si rekla; samo najprije umijesi meni kolačić, pa mi donesi; a onda zgotovi za sebe i za svoga sina."},{"v":14,"t":"Jer ovako govori Jahve, Bog Izraelov: 'U ćupu neće brašna nestati ni vrč se s uljem neće isprazniti sve dokle Jahve ne pusti da kiša padne na zemlju.'”"},{"v":15,"t":"Ode ona i učini kako je rekao Ilija; i za mnoge dane imadoše jela, ona, on i njen sin."},{"v":16,"t":"Brašno se iz ćupa nije potrošilo i u vrču nije nestalo ulja, po riječi koju je Jahve rekao preko svoga sluge Ilije."},{"v":17,"t":"Poslije ovih događaja razbolio se sin domaćičin i bolest se njegova jako pogoršala, tako te u njemu nije ostalo daha."},{"v":18,"t":"Tada ona reče Iliji: “Što ja imam s tobom, čovječe Božji? Zar si došao k meni da me podsjetiš na moj grijeh i da mi usmrtiš sina!”"},{"v":19,"t":"On joj reče: “Daj mi svoga sina!” Tada ga uze iz njezina naručja, odnese ga u gornju sobu gdje je stanovao i položi ga na svoju postelju."},{"v":20,"t":"Tada zavapi Jahvi i reče: “Jahve, Bože moj, zar zaista želiš udovicu koja me ugostila uvaliti u tugu umorivši joj sina?”"},{"v":21,"t":"Zatim se tri puta pružio nad dječakom zazivajući Jahvu: “Jahve, Bože, učini da se u ovo dijete vrati duša njegova!”"},{"v":22,"t":"Jahve je uslišio molbu Ilijinu, u dijete se vratila duša i ono oživje."},{"v":23,"t":"Ilija ga uze, siđe iz gornje sobe u kuću i dade ga njegovoj materi; i reče Ilija: “Evo, tvoj sin živi!”"},{"v":24,"t":"Žena mu reče: “Sada znam da si ti čovjek Božji i da je riječ Jahvina u tvojim ustima istinita!”"}]},"18":{"hr":[{"v":1,"t":"Prošlo je mnogo vremena i riječ Jahvina bi upravljena treće godine Iliji: “Idi, pokaži se Ahabu, jer želim pustiti kišu na lice zemlje.”"},{"v":2,"t":"I ode Ilija da se pokaže Ahabu. Kako je glad u Samariji bivala teža,"},{"v":3,"t":"pozva Ahab dvorskog upravitelja Obadiju. Taj se Obadija veoma bojao Jahve;"},{"v":4,"t":"jer kad je Izebela poubijala proroke Jahvine, on je uzeo stotinu proroka i sakrio ih po pedeset u jednu spilju, gdje ih je hranio kruhom i pojio vodom."},{"v":5,"t":"I reče Ahab Obadiji: “Hajde, obići ćemo svu zemlju, sve izvore i sve potoke, možda ćemo naći trave da sačuvamo u životu konje i mazge i da nam ne propadne stoka.”"},{"v":6,"t":"Podijelili su zemlju koju će pretražiti: Ahab je sam otišao jednim putem, a Obadija je pošao sam drugim putem."},{"v":7,"t":"I kad je Obadija bio na putu, eto mu u susret Ilije; poznavši ga, pade ničice i reče: “Jesi li to ti, gospodaru Ilija!”"},{"v":8,"t":"On mu odgovori: “Ja sam! Idi i reci svome gospodaru: 'Evo Ilije!'”"},{"v":9,"t":"Odgovori mu Obadija: “Što sam sagriješio te slugu svojega predaješ u ruke Ahabu da me ubije?"},{"v":10,"t":"Živoga mi Jahve, tvoga Boga, nema naroda ili kraljevstva kamo moj gospodar nije slao da te traže. I kad su mu rekli: 'Nema ga!' zakleo je kraljevstvo i narod što te nisu našli."},{"v":11,"t":"I sada mi naređuješ: 'Idi, reci svome gospodaru: Evo Ilije!'"},{"v":12,"t":"Ali kad ja odem od tebe, Duh Jahvin odnijet će te ne znam kamo, a ja ću doći i obavijestiti Ahaba. Pa kad te ne nađe, ubit će me! A tvoj se sluga boji Jahve od mladosti svoje!"},{"v":13,"t":"Zar nije poznato mome gospodaru što sam učinio kad je ono Izebela poubijala proroke Jahvine? Sakrio sam stotinu proroka, po pedeset u jednu spilju, i kruhom ih uzdržavao i vodom."},{"v":14,"t":"I sada ti naređuješ: 'Idi, reci svome gospodaru: Evo Ilije!' Pa on će me ubiti!”"},{"v":15,"t":"Ilija mu odgovori: “Živoga mi Jahve Sebaota, komu služim, još ću mu se danas pokazati.”"},{"v":16,"t":"Obadija pođe u susret Ahabu i donese mu vijest, a Ahab pođe u susret Iliji."},{"v":17,"t":"Kad Ahab ugleda Iliju, reče mu: “Jesi li ti onaj koji upropašćuješ Izraela?”"},{"v":18,"t":"Ilija odgovori: “Ne upropašćujem ja Izraela, nego ti i tvoja obitelj, jer ste ostavili Jahvu, a ti si sljedbenik Baala."},{"v":19,"t":"Sada sakupi sav Izrael preda me na gori Karmelu i četiri stotine pedeset proroka Baalovih koji jedu za stolom Izebelinim.”"},{"v":20,"t":"Ahab pozva sve sinove Izraelove i sakupi proroke na gori Karmelu."},{"v":21,"t":"Ilija pristupi svemu narodu i reče: “Dokle ćete hramati na obje strane? Ako je Jahve Bog, slijedite ga; ako je Baal, slijedite njega.” A narod mu nije ništa odgovorio."},{"v":22,"t":"Ilija nastavi: “Ja sam još jedini ostao kao prorok Jahvin, a Baalovih je proroka četiri stotine i pedeset."},{"v":23,"t":"Dajte nam dva junca. Neka oni izaberu sebi jednoga, neka ga sasijeku i stave na drva, ali neka ne podmeću ognja. Ja ću spremiti drugoga junca i neću podmetati ognja."},{"v":24,"t":"Vi zazovite ime svoga boga, a ja ću zazvati ime Jahvino: bog koji odgovori ognjem pravi je Bog.” Sav narod odgovori: “Dobro!”"},{"v":25,"t":"Potom reče Ilija prorocima Baalovim: “Izaberite sebi jednoga junca i počnite, jer vas je mnogo više. Zazovite ime svoga boga, ali ne stavljajte ognja.”"},{"v":26,"t":"Oni uzeše junca koji je njima pripao i pripremiše ga. Zazivali su ime Baalovo od jutra do podne govoreći: “O Baale, usliši nas!” Ali nije bilo ni glasa, ni odgovora. I skakahu i prigibahu koljena pred žrtvenikom koji su načinili."},{"v":27,"t":"U podne im se Ilija naruga i reče: “Glasnije vičite, jer on je bog; zauzet je, ili ima posla, ili je na putu; možda spava, pa ga treba probuditi!”"},{"v":28,"t":"A oni okrenuše vikati još glasnije i parati se noževima i sulicama, kako je u njih običaj, sve dok ih nije oblila krv."},{"v":29,"t":"Kad je prošlo podne, pali su u bunilo i bjesnjeli sve dok nije bilo vrijeme da se prinese žrtva; ali nije bilo nikakva glasa ni odgovora niti znaka da ih tkogod sluša."},{"v":30,"t":"Tada Ilija reče svemu narodu: “Priđite k meni!” I sav mu narod pristupi. On popravi žrtvenik Jahvin koji bijaše srušen."},{"v":31,"t":"Ilija uze dvanaest kamenova prema broju plemena sinova Jakova, kome je Bog rekao: “Izrael će biti ime tvoje!”"},{"v":32,"t":"I sagradi od toga kamenja žrtvenik Imenu Jahvinu i iskopa jarak oko žrtvenika, širok da bi se mogle posijati dvije mjere pšenice."},{"v":33,"t":"Složi drva, rasiječe junca i stavi ga na drva."},{"v":34,"t":"Tada reče: “Napunite vodom četiri vrča i izlijte na paljenicu i na drva!” Učiniše tako. Zapovjedi im: “Ponovite”, i oni ponoviše. Tada reče: “Učinite i treći put.” Oni tako i treći put."},{"v":35,"t":"Voda je tekla oko žrtvenika i jarak se ispunio vodom."},{"v":36,"t":"Kad bijaše vrijeme da se prinese žrtva, pristupi prorok Ilija i reče: “Jahve, Bože Abrahamov, Izakov i Izraelov, objavi danas da si ti Bog u Izraelu, da sam ja sluga tvoj i da sam po zapovijedi tvojoj učinio sve ovo."},{"v":37,"t":"Usliši me, Jahve; usliši me, da bi sav ovaj narod znao da si ti, Jahve, Bog i da ćeš ti obratiti njihova srca.”"},{"v":38,"t":"I oganj Jahvin pade i proguta paljenicu i drva, kamenje i prašinu, čak i vodu u jarku isuši."},{"v":39,"t":"Sav narod se uplaši, ljudi padoše ničice i rekoše: “Jahve je Bog! Jahve je Bog!”"},{"v":40,"t":"Ilija im reče: “Pohvatajte proroke Baalove da nijedan od njih ne utekne!” I oni ih pohvataše. Ilija ih odvede do potoka Kišona i ondje ih pobi."},{"v":41,"t":"Ilija reče Ahabu: “Idi gore, jedi i pij, jer čujem šumor kiše.”"},{"v":42,"t":"Dok je Ahab otišao gore da jede i pije, Ilija se popeo na vrh Karmela, prignuo se zemlji i sakrio lice među koljena."},{"v":43,"t":"Rekao je zatim svome momku: “Idi gore i pogledaj prema moru.” On ode gore, pogleda i reče: “Ništa nema ondje!” Ilija odgovori: “Vrati se sedam puta.”"},{"v":44,"t":"Ali sedmoga puta reče momak: “Eno se oblak, malen kao dlan čovječji, diže od mora.” Tada reče Ilija: “Idi, kaži Ahabu: 'Upregni i silazi da te kiša ne uhvati.'”"},{"v":45,"t":"Odjednom se nebo zamrači od oblaka i vihora i pade jaka kiša. Ahab se pope na kola i odveze u Jizreel."},{"v":46,"t":"Ruka je Jahvina bila nad Ilijom te on, opasavši se, otrča pred Ahabom sve do u blizinu Jizreela."}]},"19":{"hr":[{"v":1,"t":"Ahab ispriča Izebeli sve što je Ilija učinio i kako je mačem poubijao sve proroke."},{"v":2,"t":"Tada Izebela posla Iliji glasnika s porukom: “Neka mi bogovi učine sva zla i neka nadodadu, ako sutra u ovo doba ne učinim s tvojim životom kao što si ti učinio sa životom svakoga od njih!”"},{"v":3,"t":"On se uplaši, ustade i ode da bi spasio život. Došao je u Beer Šebu, koja je u Judeji, i otpustio ondje svoga momka."},{"v":4,"t":"A sam ode dan hoda u pustinju; sjede ondje pod smreku, zaželje umrijeti i reče: “Već mi je svega dosta, Jahve! Uzmi dušu moju, jer nisam bolji od otaca svojih.”"},{"v":5,"t":"Zatim leže i zaspa. Ali gle, anđeo ga taknu i reče mu: “Ustani i jedi.”"},{"v":6,"t":"On pogleda, kad gle - kraj njegova uzglavlja na kamenu pečen kruh i vrč vode. Jeo je i pio, pa opet legao."},{"v":7,"t":"Ali se anđeo Jahvin javi i drugi put, dotače ga i reče: “Ustani i jedi, jer je pred tobom dalek put!”"},{"v":8,"t":"Ustao je, jeo i pio. Okrijepljen tom hranom, išao je četrdeset dana i četrdeset noći sve do Božje gore Horeba."},{"v":9,"t":"Ondje je ušao u neku spilju i prenoćio u njoj. I gle, eto k njemu riječi Jahvine: “Što ćeš ti ovdje, Ilija?”"},{"v":10,"t":"On odgovori: “Revnovao sam gorljivo za Jahvu, Boga nad vojskama, jer su sinovi Izraelovi napustili tvoj Savez, srušili tvoje žrtvenike i pobili mačem tvoje proroke. Ostao sam sam, a oni traže da i meni uzmu život.”"},{"v":11,"t":"Glas mu reče: “Iziđi i stani u gori pred Jahvom. Evo Jahve upravo prolazi.” Pred Jahvom je bio silan vihor, tako snažan da je drobio brda i lomio hridi, ali Jahve nije bio u olujnom vihoru; poslije olujnog vihora bio je potres, ali Jahve nije bio u potresu;"},{"v":12,"t":"a poslije potresa bio je oganj, ali Jahve nije bio u ognju; poslije ognja šapat laganog i blagog lahora."},{"v":13,"t":"Kad je to čuo Ilija, zakri lice plaštem, iziđe i stade na ulazu u pećinu. Tada mu progovori glas i reče: “Što ćeš ovdje, Ilija?”"},{"v":14,"t":"On odgovori: “Revnovao sam veoma gorljivo za Jahvu nad vojskama, jer su sinovi Izraelovi napustili tvoj Savez, srušili tvoje žrtvenike i mačem poubijali tvoje proroke. Ostadoh sam, a oni traže da i meni oduzmu život.”"},{"v":15,"t":"Jahve mu reče: “Idi, vrati se istim putem u damaščansku pustinju. Kad dođeš, pomaži ondje Hazaela za kralja aramskog."},{"v":16,"t":"Pomaži Jehuu, sina Nimsijeva, za kralja izraelskoga i pomaži Elizeja, sina Šafatova, iz Abel Mehole, za proroka namjesto sebe."},{"v":17,"t":"Koji utekne od mača Hazaelova, njega će pogubiti Jehu; a tko utekne od Jehuova mača, njega će pogubiti Elizej."},{"v":18,"t":"Ali ću ostaviti u Izraelu sedam tisuća, sve koljena koja se nisu savila pred Baalom i sva usta koja ga nisu cjelivala.”"},{"v":19,"t":"Ode on i na povratku naiđe na Elizeja, sina Šafatova, gdje ore: pred njim dvanaest jarmova, sam bijaše kod dvanaestoga. Ilija prođe kraj njega i baci na nj svoj plašt."},{"v":20,"t":"On ostavi volove, potrča za Ilijom i reče: “Dopusti mi da zagrlim svoga oca i majku, pa ću poći za tobom.” Ilija mu odgovori: “Idi, vrati se, jer što sam ti učinio?”"},{"v":21,"t":"On ga ostavi, uze jaram volova i žrtvova ih. Volujskim jarmom skuha meso i dade ga ljudima da jedu. Zatim ustade i pođe za Ilijom da ga poslužuje."}]},"20":{"hr":[{"v":1,"t":"Ben-Hadad, kralj Arama, skupi svu vojsku svoju - s njim bijahu trideset i dva kralja, s konjima i bojnim kolima - i ode opsjedati Samariju i udari na nju."},{"v":2,"t":"Posla u grad glasnike izraelskom kralju Ahabu"},{"v":3,"t":"i reče mu: “Ovako veli Ben-Hadad: 'Tvoje srebro i tvoje zlato moje je, a žene tvoje i djeca ostaju tebi.'”"},{"v":4,"t":"Izraelski kralj ovako mu odgovori: “Na tvoju zapovijed, gospodaru kralju! Tvoj sam ja sa svime što mi pripada.”"},{"v":5,"t":"Ali se glasnici vratiše i rekoše: “Ovako kaže Ben-Hadad i poručuje ti: 'Daj mi svoje srebro i zlato, svoje žene i djecu."},{"v":6,"t":"Budi siguran da ću sutra u ovo doba poslati svoje sluge i oni će pretražiti tvoju kuću i kuće tvojih sluga i stavit će svoju ruku na sve što im se svidi i to će odnijeti.'”"},{"v":7,"t":"Izraelski kralj sazva sve starješine zemaljske i reče: “Promislite i pogledajte! Ovaj nam sprema zlo! Traži od mene moje žene i djecu, premda mu nisam odbio svoje srebro i zlato.”"},{"v":8,"t":"Starješine mu i sav narod odgovoriše: “Nemoj poslušati! Nemoj pristati!”"},{"v":9,"t":"Tada on ovako odgovori Ben-Hadadovim poslanicima: “Recite gospodaru kralju: 'Sve što si prvi put tražio od svoga sluge, ja ću učiniti, ali ovo drugo ne mogu.'” I poslanici odoše i odnesoše odgovor."},{"v":10,"t":"Tada mu Ben-Hadad poruči: “Neka mi bogovi učine zlo i neka pridaju još toliko, ako bude dosta praha Samarije da svi oni koji me slijede dobiju po pregršt!”"},{"v":11,"t":"Ali mu kralj izraelski odgovori: “Kaže se: 'Neka se ne hvali koji se opasuje kao onaj koji se raspasuje!'”"},{"v":12,"t":"A kad je Ben-Hadad to čuo - upravo je pio s kraljevima pod šatorima - zapovjedi svojim slugama: “Na svoja mjesta!” I oni zauzeše svoje položaje protiv grada."},{"v":13,"t":"Tada potraži jedan prorok Ahaba, kralja Izraela, i reče: “Ovako veli Jahve: 'Jesi li vidio ono silno mnoštvo? Ja ću ti ga danas evo predati u ruke i ti ćeš spoznati da sam ja Jahve.'”"},{"v":14,"t":"Ahab reče: “Po kome?” On odgovori: “Ovako veli Jahve: po momcima pokrajinskih namjesnika.” Ahab upita: “Tko će početi boj?” On odgovori: “Ti!”"},{"v":15,"t":"Ahab izvrši smotru momaka pokrajinskih upravitelja. Bijaše ih dvije stotine trideset i dva. Poslije njih izvršio je smotru sve vojske svih Izraelaca. Bijaše ih sedam tisuća."},{"v":16,"t":"Oni iziđoše u podne, dok je Ben-Hadad pio u šatorima sa trideset i dva kralja koji mu bijahu saveznici."},{"v":17,"t":"Momci pokrajinskih upravitelja iziđoše prvi. Obavijestiše Ben-Hadada: “Izišli su ljudi iz Samarije.”"},{"v":18,"t":"On reče: “Ako su izišli radi mira, pohvatajte ih žive; ako su izišli u boj, opet ih uhvatite žive!”"},{"v":19,"t":"Ali kad su oni - momci pokrajinskih upravitelja - izišli iz grada, za njima je slijedila ostala vojska"},{"v":20,"t":"i svaki je udario na svog protivnika. Aramejci su bježali, a Izraelci ih progonili. Ben-Hadad, aramejski kralj, spasio se na konju zajedno s nekim konjanicima."},{"v":21,"t":"Tada je izišao izraelski kralj; zarobio je konje i kola i nanio Aramejcima težak poraz."},{"v":22,"t":"Tada pristupi prorok izraelskom kralju i reče mu: “Hajdemo! Ohrabri se i razmisli dobro što ti je činiti, jer će dogodine aramejski kralj napasti na te.”"},{"v":23,"t":"Sluge su savjetovale aramejskog kralja: Njihov bog je bog gora, i zato su bili jači od nas. Ali ako se pobijemo s njima u ravnici, sigurno ćemo mi biti jači od njih."},{"v":24,"t":"Učinimo dakle ovako: makni ove kraljeve i postavi na njihovo mjesto upravitelje."},{"v":25,"t":"Zatim skupi sebi veliku vojsku kolika je bila ona koju si izgubio, toliko konja i toliko kola. Tada ćemo se pobiti s njima u ravnici, i sigurno ćemo ih nadvladati.” On ih posluša i učini tako."},{"v":26,"t":"Na početku godine Ben-Hadad podiže Aramejce i pođe na Afek da vojuje s Izraelom."},{"v":27,"t":"Izraelci se podigoše i krenuše protiv njih. I utaboriše se Izraelci pred njima kao dva mala stada koza, dok su Aramejci prekrili zemlju."},{"v":28,"t":"Tada pristupi Božji čovjek izraelskom kralju i reče: “Ovako veli Jahve: 'Zato što Aramejci kažu za Jahvu da je Bog bregova i da nije Bog ravnica, ja ću predati u tvoje ruke ovo silno mnoštvo da spoznate da sam ja Jahve'.”"},{"v":29,"t":"Sedam dana bijahu utaboreni jedni sučelice drugima. Sedmoga dana zametnu se boj i Izraelci poubijaše Aramejce, stotinu tisuća pješaka u jedan jedini dan."},{"v":30,"t":"Ostatak pobježe u Afek, u grad, ali se sruši zidina na dvadeset i sedam tisuća ljudi koji su ostali. Pobjegao je i Ben-Hadad. U gradu je prelazio iz jednog skrovišta u drugo."},{"v":31,"t":"Njegove su mu sluge rekle: “Gle! Mi smo čuli da su izraelski kraljevi milosrdni. Stavimo kostrijet oko bokova svojih i konope oko svojih glava, pa izađimo pred kralja izraelskog: možda će ti poštedjeti život.”"},{"v":32,"t":"I svezaše kostrijeti oko bokova svojih i konopce oko svojih glava. Otišli su pred izraelskog kralja i rekli: “Tvoj sluga Ben-Hadad kaže: 'Ostavi me na životu!'” On odgovori: “Je li još živ? On je moj brat.”"},{"v":33,"t":"Ljudi su to uzeli kao dobar znak i požurili se da ga uhvate za riječ govoreći: “Ben-Hadad tvoj je brat.” Ahab odgovori: “Idite! Dovedite ga!” Ben-Hadad dođe i on ga uze na kola."},{"v":34,"t":"Ben-Hadad reče mu tada: “Vratit ću ti gradove koje je moj otac uzeo tvome ocu; stajat će ti na raspolaganju četvrti u Damasku, kao što ih je postavio moj otac u Samariji. Pod ovim me uvjetom otpusti.” Ahab sklopi s njime savez i otpusti ga."},{"v":35,"t":"Neki od proročkih sinova reče po Jahvinoj zapovijedi svome drugu: “Udari me!” Ali čovjek ne htjede da ga tuče."},{"v":36,"t":"Tada mu onaj reče: “Budući da nisi slušao glasa Jahvina, evo, kad odeš od mene, lav će te razderati.” Tek što se udaljio od njega, naiđe na lava koji ga razdera."},{"v":37,"t":"Prorok nađe drugoga čovjeka i reče: “Udari me!” Čovjek ga izudara i izrani."},{"v":38,"t":"Prorok ode, postavi se kralju na put, a preko očiju navuče povez da ga ne prepoznaju."},{"v":39,"t":"Kad je kralj prolazio, on povika: “Tvoj je sluga bio izišao u boj, kadli iz bojnih redova jedan istupi i dovede mi nekog čovjeka govoreći: 'Čuvaj ovoga čovjeka! Ako nestane, tvoj će život biti za njegov život, ili ćeš platiti srebrni talenat.'"},{"v":40,"t":"I dok je tvoj sluga radio ovdje-ondje, njega je nestalo.” Tada mu reče kralj Izraela: “Eto ti presude! Sam si je izrekao!”"},{"v":41,"t":"Nato onaj odmah ukloni povez s očiju i kralj izraelski vidje da je to jedan od proroka."},{"v":42,"t":"A on reče kralju: “Ovako veli Jahve: 'Budući da si pustio da ti iz ruke utekne čovjek koga sam udario prokletstvom, tvoj će život biti za njegov život, tvoj narod za njegov narod.'”"},{"v":43,"t":"I kralj izraelski ode svojoj kući, mrk i srdit, i uđe u Samariju."}]},"21":{"hr":[{"v":1,"t":"Nakon tih događaja dogodilo se ovo: Nabot Jizreelac imao vinograd kraj palače Ahaba, kralja samarijskog,"},{"v":2,"t":"i Ahab ovako reče Nabotu: “Ustupi mi svoj vinograd da mi bude za povrtnjak jer je blizu moje kuće. Ja ću ti dati za nj bolji vinograd, ili, ako to želiš, dat ću ti novca koliko vrijedi.”"},{"v":3,"t":"Ali Nabot reče Ahabu: “Jahve me sačuvao od toga da ti ustupim baštinu svojih otaca!”"},{"v":4,"t":"Ahab se vrati kući mrk i ljutit zbog riječi koju mu je Nabot Jizreelac rekao: “Ne dam ti baštine svojih otaca.” Legao je na postelju i okrenuo lice i nije htio okusiti hrane."},{"v":5,"t":"Dođe mu njegova žena Izebela i reče: “Zašto si zlovoljan i ne mariš za hranu?”"},{"v":6,"t":"On joj odgovori: “Govorio sam Nabotu Jizreelcu i rekao mu: 'Ustupi mi svoj vinograd za novac, ili, ako ti je draže, dat ću ti drugi vinograd za taj.' Ali mi je on rekao: 'Ne dam ti svoga vinograda.'”"},{"v":7,"t":"Tada mu žena Izebela reče: “Jesi li ti onaj koji kraljuje nad Izraelom! Ustani i jedi i budi dobre volje. Ja ću ti pribaviti vinograd Nabota Jizreelca.”"},{"v":8,"t":"I napisa ona pisma u ime Ahabovo i zapečati ih kraljevskim pečatom. Pisma je poslala starješinama i glavarima Nabotovim sugrađanima."},{"v":9,"t":"U tim je pismima napisala: “Proglasite post i postavite Nabota na čelo naroda."},{"v":10,"t":"Postavite prema njemu dva nitkova koji će ga optužiti: 'Proklinjao si Boga i kralja!' Tada ga izvedite i kamenujte ga da pogine.”"},{"v":11,"t":"I učiniše ljudi Nabotova grada, starješine i glavari, kako im je Izebela zapovjedila i kako je pisalo u pismima koja im je uputila."},{"v":12,"t":"Proglasiše post i Nabota postaviše na čelo naroda."},{"v":13,"t":"Tada dođoše dva nitkova, sjedoše mu nasuprot i optužiše Nabota pred narodom: “Nabot je proklinjao Boga i kralja.” I tako izvedoše Nabota izvan grada, zasuše ga kamenjem i on pogibe."},{"v":14,"t":"Zatim poručiše Izebeli: “Nabot je kamenovan i umro je.”"},{"v":15,"t":"Pošto je Izebela čula da je Nabot kamenovan i da je umro, reče Ahabu: “Ustani i zaposjedni vinograd što ti ga Nabot Jizreelac ne htjede ustupiti za novac. Nabot više nije živ, on je mrtav.”"},{"v":16,"t":"Kada je Ahab doznao da je Nabot mrtav, ustade i siđe u vinograd Nabota Jizreelca da ga zaposjedne."},{"v":17,"t":"Tada bi upućena riječ Jahvina Iliji Tišbijcu:"},{"v":18,"t":"“Ustani i siđi u Samariju, u susret Ahabu, kralju izraelskom. Eno ga u vinogradu Nabotovu u koji je sišao da ga zaposjedne."},{"v":19,"t":"Reci mu: 'Ovako veli Jahve: Umorio si, oteo si! Zato ovako veli Jahve: Na mjestu gdje su psi lizali Nabotovu krv, lizat će psi i tvoju.'”"},{"v":20,"t":"Ahab reče Iliji: “Nađe li me, neprijatelju moj?” Ilija odgovori: “Nađoh te, jer si se prodao da činiš što je zlo u očima Jahvinim."},{"v":21,"t":"Evo, tek što nisam navukao na te nesreću. Pomest ću tvoje potomstvo, istrijebiti Ahabu sve što mokri uza zid, robove i slobodnjake u Izraelu."},{"v":22,"t":"Učinit ću s tvojom kućom kao s kućom Jeroboama, sina Nebatova, i s kućom Baše, sina Ahijina, jer si me rasrdio i naveo Izraela na grijeh."},{"v":23,"t":"I nad Izebelom reče Jahve: psi će proždrijeti Izebelu na Jizreelskom polju."},{"v":24,"t":"Tko od obitelji Ahabove umre u gradu, psi će ga izjesti, a tko umre u polju, pojest će ga ptice nebeske.”"},{"v":25,"t":"Doista, nitko se nije prodao tako kao Ahab da čini što je zlo u očima Jahvinim, jer ga je zavodila njegova žena Izebela."},{"v":26,"t":"Činio je vrlo odvratna djela: išao je za idolima baš kao što su činili Amorejci, koje je Jahve protjerao ispred Izraelaca."},{"v":27,"t":"Kad je Ahab čuo te riječi, razdrije svoje haljine i stavi kostrijet na tijelo; i postio je, u kostrijeti je spavao i naokolo išao tiho jecajući."},{"v":28,"t":"Tada dođe riječ Jahvina Iliji Tišbijcu:"},{"v":29,"t":"“Jesi li vidio kako se Ahab preda mnom ponizio? Budući da se tako ponizio preda mnom, neću zla pustiti za njegova života; u vrijeme njegova sina pustit ću zlo na kuću njegovu.”"}]},"22":{"hr":[{"v":1,"t":"Tri je godine vladao mir; nije bilo rata između Aramejaca i Izraela."},{"v":2,"t":"Treće godine Jošafat, kralj judejski, posjeti kralja izraelskoga."},{"v":3,"t":"Kralj Izraela reče svojim dvoranima: “Znate li da je Ramot Gilead naš? A mi ne poduzimamo ništa da ga otmemo iz ruke aramejskog kralja.”"},{"v":4,"t":"Zatim reče Jošafatu: “Hoćeš li poći sa mnom na Ramot Gilead?” Jošafat odgovori kralju izraelskom: “Ja sam kao i ti, moj narod kao i tvoj, moji konji što i tvoji.”"},{"v":5,"t":"Tada Jošafat reče kralju izraelskom: “De posavjetuj se najprije s Jahvom.”"},{"v":6,"t":"Tada kralj izraelski sakupi oko četiri stotine proroka i upita ih: “Mogu li zavojštiti na Ramot Gilead ili da se okanim toga?” Oni odgovoriše: “Idi, jer će ga Jahve predati kralju u ruke.”"},{"v":7,"t":"Ali Jošafat upita: “Ima li ovdje još koji prorok Jahvin da i njega upitamo?”"},{"v":8,"t":"Kralj izraelski odgovori Jošafatu: “Ima još jedan čovjek preko koga bismo mogli upitati Jahvu, ali ga ne podnosim jer mi ne prorokuje ništa dobro nego samo zlo; to je Mihej, sin Jimlin.” A Jošafat reče: “Neka kralj ne govori tako!”"},{"v":9,"t":"Tada kralj izraelski dozva jednoga dvoranina i reče mu: “Brže dovedi Jimlina sina Miheja.”"},{"v":10,"t":"Izraelski kralj i judejski kralj Jošafat sjedili su svaki na svome prijestolju, u svečanim haljinama pred Samarijskim vratima, a proroci proricali pred njima."},{"v":11,"t":"Kenaanin sin Sidkija napravi sebi željezne rogove i reče: “Ovako govori Jahve: 'Njima ćeš nabosti sve Aramejce dok ih ne uništiš'.”"},{"v":12,"t":"Tako su i svi drugi proroci proricali govoreći: “Idi na Ramot Gilead i uspjet ćeš: Jahve će ga predati kralju u ruke.”"},{"v":13,"t":"Glasnik koji bijaše otišao da zove Miheja reče mu: “Eno, svi proroci složno proriču dobro kralju. Govori i ti kao jedan od njih i proreci mu uspjeh!”"},{"v":14,"t":"Ali Mihej odvrati: “Živoga mi Jahve, govorit ću ono što mi Jahve kaže!”"},{"v":15,"t":"Kad dođe pred kralja, upita ga kralj: “Miheju, da pođem u rat na Ramot Gilead ili da se okanim toga?” On odgovori: “Pođi! Uspjet ćeš: Jahve će ga dati u ruke kraljeve.”"},{"v":16,"t":"Ali mu kralj reče: “Koliko ću te puta zaklinjati da mi kažeš samo istinu u Jahvino ime?”"},{"v":17,"t":"Tada Mihej odgovori: “Sav Izrael vidim rasut po gorama kao stado bez pastira. I Jahve veli: 'Nemaju više gospodara, neka se u miru kući vrate.'”"},{"v":18,"t":"Tada izraelski kralj reče Jošafatu: “Nisam li ti rekao da mi neće proreći dobro nego zlo!”"},{"v":19,"t":"A Mihej reče: “Zato čuj riječ Jahvinu: vidio sam Jahvu gdje sjedi na svome prijestolju, a sva mu vojska nebeska stajaše zdesna i slijeva."},{"v":20,"t":"Jahve upita: 'Tko će zavesti Ahaba da otiđe i padne u Ramot Gileadu?' Jedan reče ovo, drugi ono."},{"v":21,"t":"Tada uđe jedan duh i stade pred Jahvu. 'Ja ću ga', reče, 'zavesti.' Jahve ga upita: 'Kako?'"},{"v":22,"t":"On odgovori: 'Izaći ću i bit ću lažljiv duh u ustima svih njegovih proroka.' Jahve reče: 'Ti ćeš ga zavesti. I uspjet ćeš. Idi i učini tako!'"},{"v":23,"t":"Tako je, evo, Jahve stavio lažljiva duha u usta svih ovih tvojih proroka, ali ti Jahve navješćuje zlo.”"},{"v":24,"t":"Tada pristupi Kenaanin sin Sidkija i udari Miheja po obrazu pitajući: “Zar je Jahvin duh napustio mene da bi s tobom govorio?”"},{"v":25,"t":"Mihej odgovori: “Vidjet ćeš onoga dana kad budeš bježao iz sobe u sobu da se sakriješ.”"},{"v":26,"t":"Tada izraelski kralj naredi: “Uhvati Miheja i odvedi ga gradskom zapovjedniku Amonu i kraljeviću Joašu."},{"v":27,"t":"Reci im: Ovako veli kralj: 'Bacite ovoga u tamnicu i držite ga na suhu kruhu i vodi dok se sretno ne vratim.'”"},{"v":28,"t":"Mihej reče: “Ako se doista sretno vratiš, onda Jahve nije govorio iz mene.” I nadoda: “Čujte, svi puci!”"},{"v":29,"t":"Izraelski kralj i judejski kralj Jošafat krenuše na Ramot Gilead."},{"v":30,"t":"Izraelski kralj reče Jošafatu: “Ja ću se preobući i onda ući u boj, ali ti ostani u svojoj odjeći!” Izraelski se kralj preobuče i pođe u boj."},{"v":31,"t":"Aramejski kralj naredi zapovjednicima bojnih kola: “Ne napadajte ni na maloga ni na velikoga, nego jedino na izraelskog kralja!”"},{"v":32,"t":"Kad zapovjednici bojnih kola ugledaše Jošafata, rekoše: “To je kralj izraelski!” I krenuše u boj prema njemu. A Jošafat povika."},{"v":33,"t":"A kad zapovjednici bojnih kola vidješe da to nije izraelski kralj, okrenuše se od njega."},{"v":34,"t":"Jedan nasumce odape luk i ustrijeli izraelskog kralja između nabora pojasa i oklopa. Kralj reče vozaču: “Okreni, izvedi me iz boja jer mi nije dobro.”"},{"v":35,"t":"Boj je onoga dana bio sve žešći, ali se kralj držao uspravno na bojnim kolima prema Aramejcima. A navečer umrije. Krv se iz rane izlila u kola."},{"v":36,"t":"O zalasku sunčevu odjeknu glas taborom: “Svaki u svoj grad i svaki u svoju zemlju!"},{"v":37,"t":"Kralj je poginuo!” Otišli su u Samariju i pokopali kralja u Samariji."},{"v":38,"t":"Njegova su kola oprali u samarijskom ribnjaku, psi su lizali njegovu krv i bludnice se ondje kupale, po riječi koju je rekao Jahve."},{"v":39,"t":"Ostala povijest Ahabova, sve što je učinio, o kući od bjelokosti, o svim gradovima koje je sagradio, zar sve to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":40,"t":"Ahab je počinuo sa svojim ocima, a njegov sin Ahazja zakralji se mjesto njega."},{"v":41,"t":"Jošafat, sin Asin, postade kraljem Judeje četvrte godine kraljevanja Ahaba, kralja izraelskoga."},{"v":42,"t":"Jošafatu bijaše trideset i pet godina kad se zakraljio; kraljevao je dvadeset i pet godina u Jeruzalemu; mati mu se zvala Azuba, a bila je kći Šilhijeva."},{"v":43,"t":"Išao je sasvim putem oca Ase, ne skrećući s njega, nego čineći što je pravo u očima Jahvinim."},{"v":44,"t":"Samo, uzvišice nisu bile uklonjene, narod je još prinosio klanice i kađenice na uzvišicama."},{"v":45,"t":"Jošafat je bio u miru s izraelskim kraljem."},{"v":46,"t":"Ostala povijest Jošafatova, pothvati koje je izveo i kako je vojevao, zar to nije zapisano u knjizi Ljetopisa kraljeva judejskih?"},{"v":47,"t":"Istrijebio je iz zemlje preostale bludnice, koje su se održale iz vremena njegova oca Ase."},{"v":48,"t":"Nije bilo kralja u Edomu, nego je vladao namjesnik."},{"v":49,"t":"Kralj Jošafat sagradi taršiško brodovlje da ide u Ofir po zlato, ali nije otišlo jer se brodovlje razbilo kod Esjon Gebera."},{"v":50,"t":"Tada Ahazja, sin Ahabov, reče Jošafatu: “Neka moje sluge pođu s tvojim slugama na lađama.” Ali Jošafat to ne prihvati."},{"v":51,"t":"Jošafat počinu sa svojim ocima i sahranjen bi u gradu Davida, svoga praoca. Na njegovo se mjesto zakraljio sin mu Joram."},{"v":52,"t":"Ahazja, sin Ahabov, postade kraljem Izraela u Samariji sedamnaeste godine Jošafatova kraljevanja Judejom i kraljevao je dvije godine nad Izraelom."},{"v":53,"t":"On je činio što je zlo u očima Jahvinim i hodio je putem svoga oca i putem svoje majke i putem Jeroboama, sina Nebatova, koji je navodio Izraela na grijeh."},{"v":54,"t":"Služio je Baalu i klanjao se pred njim. Srdio je Jahvu, Boga Izraelova, sasvim onako kako je činio njegov otac."}]}},"2KI":{"1":{"hr":[{"v":1,"t":"Poslije smrti Ahabove pobuni se Moab protiv Izraela."},{"v":2,"t":"Kako Ahazja bijaše pao preko prozorske rešetke svoje gornje odaje u Samariji i ozlijedio se, posla glasnike kojima reče: “Idite, pitajte Baal Zebuba, boga ekronskog, hoću li ozdraviti od ove bolesti.”"},{"v":3,"t":"Ali je Anđeo Jahvin rekao Iliji Tišbijcu: “Ustani! Idi u susret glasnicima samarijanskoga kralja i reci im: 'Zar nema Boga u Izraelu te se idete savjetovati s Baal Zebubom, bogom ekronskim?'"},{"v":4,"t":"I zato veli Jahve ovako: 'Nećeš sići s postelje u koju si se popeo; sigurno ćeš umrijeti.'” I ode Ilija."},{"v":5,"t":"Glasnici se vratiše k Ahazji, a on im reče: “Kako to da ste se već vratili?”"},{"v":6,"t":"Oni mu odgovoriše: “Sreo nas neki čovjek i rekao nam: 'Idite, vratite se pred kralja koji vas je poslao i recite mu: Ovako veli Jahve: Zar nema Boga u Izraelu te si poslao po savjet k Baal Zebubu, bogu ekronskom? Zato nećeš sići s postelje na koju si se popeo, nego ćeš umrijeti.'”"},{"v":7,"t":"On ih upita: “Kakav bijaše na oči taj čovjek koji vas je sreo i rekao vam te riječi?”"},{"v":8,"t":"A oni mu odgovoriše: “Bio je to čovjek u kožuhu i s kožnim pojasom oko bedara.” On reče: “To je Ilija Tišbijac!”"},{"v":9,"t":"Tada mu posla pedesetnika s njegovom pedesetoricom i ode taj k njemu i, našavši ga gdje sjedi na vrhu brijega, reče mu: “Čovječe Božji! Kralj je naredio: Siđi!”"},{"v":10,"t":"Ilija odgovori i reče pedesetniku: “Ako sam čovjek Božji, neka oganj siđe s neba i neka te proguta, tebe i tvoju pedesetoricu.” I oganj se spusti s neba i proguta ga, njega i njegovu pedesetoricu."},{"v":11,"t":"Kralj mu posla drugoga pedesetnika i njegovu pedesetoricu; a taj, kad dođe, reče mu: “Čovječe Božji! Kralj je ovo zapovjedio: Brže siđi!”"},{"v":12,"t":"Ilija odgovori i reče mu: “Ako sam čovjek Božji, neka siđe oganj s neba i proguta tebe i tvoju pedesetoricu.” I spusti se oganj s neba i proguta ga, njega i njegovu pedesetoricu."},{"v":13,"t":"Kralj posla opet trećega pedesetnika i njegovu pedesetoricu. Treći pedesetnik dođe, prignu koljena pred Ilijom i zamoli ga ovako: “Čovječe Božji! Neka bude dragocjen u tvojim očima moj život i život ovih pedeset tvojih slugu!"},{"v":14,"t":"Oganj se spustio s neba i progutao je oba pedesetnika s njihovom pedesetoricom; ali sada neka barem moj život bude dragocjen u tvojim očima!”"},{"v":15,"t":"Anđeo Jahvin reče Iliji: “Siđi s njim, ne boj se!” On ustade i siđe s njim pred kralja"},{"v":16,"t":"i reče mu: “Ovako veli Jahve: zato što si slao glasnike Baal Zebubu, bogu ekronskom, po savjet, nećeš sići s postelje na koju si se popeo, nego ćeš umrijeti.”"},{"v":17,"t":"I umrije po riječi Jahvinoj koju je objavio Ilija. A Joram, njegov brat, zakralji se mjesto njega druge godine Jorama, sina Jošafata, judejskoga kralja, jer ovaj nije imao sinova."},{"v":18,"t":"Ostala povijest Ahazje, sve što je učinio, zar to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"}]},"2":{"hr":[{"v":1,"t":"Evo što se dogodilo kad je Jahve uznio Iliju na nebo u vihoru: Ilija i Elizej pošli iz Gilgala."},{"v":2,"t":"I reče Ilija Elizeju: “Ostani ovdje jer me Jahve šalje do Betela.” Elizej odgovori: “Života mi Jahvina i tvoga: ja te neću ostaviti!” I siđoše do Betela."},{"v":3,"t":"A proročki sinovi koji su boravili u Betelu iziđoše Elizeju u susret i rekoše mu: “Znaš li da će danas Jahve uzeti tvoga gospodara iznad tvoje glave?” On reče: “I ja to znam; tiho!”"},{"v":4,"t":"Ilija mu reče: “Elizeju! Ostani ipak ovdje jer me Jahve šalje do Jerihona.” Ali on odgovori: “Života mi Jahvina i tvoga: ja te neću ostaviti!” I uđoše u Jerihon."},{"v":5,"t":"Proročki sinovi koji su živjeli u Jerihonu priđoše Elizeju i rekoše mu: “Znaš li da će danas Jahve uzeti tvoga gospodara iznad tvoje glave?” On reče: “I ja to znam; tiho!”"},{"v":6,"t":"Ilija mu reče: “Ostani ipak ovdje jer me Jahve šalje do Jordana.” Ali on odgovori: “Života mi Jahvina i tvoga: ja te neću ostaviti!” I tako pođoše obojica."},{"v":7,"t":"I pedeset proročkih sinova pođe i zaustavi se podalje, dok su se njih dvojica zadržala na obali Jordana."},{"v":8,"t":"Tada Ilija uze svoj ogrtač, smota ga i udari njime po vodi, a voda se razdijeli na dvije strane. I obojica prijeđoše po suhu."},{"v":9,"t":"A kad prijeđoše, Ilija će Elizeju: “Traži što da ti još učinim prije nego što budem uznesen ispred tebe!” A Elizej odgovori: “Neka mi u dio padne obilje tvoga duha!”"},{"v":10,"t":"Ilija odgovori: “Mnogo tražiš: ako me budeš vidio kad budem uznesen ispred tebe, bit će ti tako; ako pak ne budeš vidio, neće ti biti.”"},{"v":11,"t":"I dok su tako išli i razgovarali, gle: ognjena kola i ognjeni konji stadoše među njih i Ilija u vihoru uziđe na nebo."},{"v":12,"t":"Elizej je gledao i vikao: “Oče moj, oče moj! Kola Izraelova i konjanici njegovi!” I više ga nije vidio. Uze tada svoje haljine i razdera ih nadvoje."},{"v":13,"t":"I podiže Ilijin plašt, koji bijaše pao s njega, te se vrati i zaustavi se na obali Jordana."},{"v":14,"t":"Uze onda Ilijin plašt i udari po vodi govoreći: “Gdje je Jahve, Bog Ilijin?” I kad udari po vodi, ona se razdijeli na dvije strane i Elizej prijeđe."},{"v":15,"t":"Proročki su sinovi to sa strane vidjeli pa rekoše: “Duh je Ilijin počinuo na Elizeju!” I krenuše mu u susret, baciše se pred njim na zemlju"},{"v":16,"t":"i rekoše mu: “Evo ovdje s tvojim slugama pedeset junaka. Dopusti im da idu tražiti tvoga gospodara; možda ga je Duh Jahvin uzdigao i bacio na koju goru ili u kakvu dolinu.” On im odgovori: “Ne šaljite nikoga.”"},{"v":17,"t":"Ali kako su oni svejednako navaljivali, reče im: “Pošaljite!” I poslaše pedesetoricu; tražili su ga tri dana, ali ga nisu našli."},{"v":18,"t":"Vratiše se Elizeju, koji je ostao u Jerihonu, i on im reče: “Nisam li vam rekao: 'Nemojte ići!'”"},{"v":19,"t":"Ljudi iz grada rekoše Elizeju: “Lijepo je u gradu, kako to može vidjeti i naš gospodar, ali je voda loša i zemlja neplodna.”"},{"v":20,"t":"On reče: “Donesite mi novu zdjelu i metnite soli u nju!” I oni mu je donesoše."},{"v":21,"t":"On tada ode na izvor, baci u nj soli i reče: “Ovako govori Jahve: 'Ozdravljam ovu vodu. Neće od nje više biti ni smrti ni neplodnosti.'”"},{"v":22,"t":"I voda postade zdrava i takva je do današnjeg dana, po riječi koju je izrekao Elizej."},{"v":23,"t":"Odatle je uzašao u Betel. Dok je išao putem, dječaci bijahu izišli iz grada i rugahu mu se govoreći: “Hodi, ćelo! Hodi, ćelo!”"},{"v":24,"t":"On se obazre, pogleda ih i prokle ih u ime Jahvino. I odmah iziđoše dva medvjeda iz šume i rastrgaše četrdeset i dvoje djece."},{"v":25,"t":"Odatle ode on na goru Karmel, a odande se vrati u Samariju."}]},"3":{"hr":[{"v":1,"t":"Joram, sin Ahabov, zakralji se nad Izraelom u Samariji osamnaeste godine Jošafatova kraljevanja u Judeji. I vladao je dvanaest godina."},{"v":2,"t":"Činio je što je zlo u očima Jahvinim, ali ne kao njegov otac i mati, jer je uklonio Baalov stup što ga bijaše podigao njegov otac."},{"v":3,"t":"Ali je prianjao uz grijeh kojim je Jeroboam, sin Nebatov, zavodio Izraela; i nije odstupao od njega."},{"v":4,"t":"Meša, kralj moapski, bio je stočar i slao je izraelskom kralju u danak stotinu tisuća janjaca i vunu od stotine tisuća ovnova."},{"v":5,"t":"Ali kad je umro Ahab, pobuni se kralj moapski protiv izraelskog kralja."},{"v":6,"t":"U to je baš vrijeme kralj Joram izišao iz Samarije i izvršio smotru svih Izraelaca."},{"v":7,"t":"Zatim je poručio judejskom kralju Jošafatu: “Moapski se kralj pobunio protiv mene. Hoćeš li sa mnom u rat protiv Moabaca?” Judejski kralj odgovori: “Hoću! Ja kao ti, moj narod kao tvoj narod, moji konji kao i tvoji konji.”"},{"v":8,"t":"I doda: “Kojim ćemo putem?” A drugi mu odgovori: “Kroz Edomsku pustinju.”"},{"v":9,"t":"I tako krenu izraelski kralj s judejskim kraljem i s kraljem edomskim. Sedam su dana lutali, a nije bilo vode četama ni stoci koja je išla za njima."},{"v":10,"t":"Tada povika kralj izraelski: “Jao, Jahve je pozvao ova tri kralja da ih preda u ruke Moapcima!”"},{"v":11,"t":"Ali Jošafat reče: “Nema li tu proroka Jahvina da se preko njega posavjetujemo s Jahvom?” Tada odgovori jedan između slugu izraelskoga kralja: “Ovdje je Elizej, sin Šafatov, koji je lijevao vodu na Ilijine ruke.”"},{"v":12,"t":"Jošafat reče: “U njega je riječ Božja.” I kralj izraelski, kralj judejski i kralj edomski odoše Elizeju."},{"v":13,"t":"A Elizej reče kralju izraelskom: “Što ja imam s tobom? Potraži proroke svoga oca i proroke svoje majke!” Izraelski kralj odgovori mu: “Ne! Jer Jahve je pozvao ova tri kralja da ih preda u ruke Moapcima.”"},{"v":14,"t":"Elizej uzvrati: “Tako mi živoga Jahve Sebaota, komu služim, kad ne bih gledao na judejskog kralja Jošafata, ne bih ti obraćao pažnje niti bih te pogledao."},{"v":15,"t":"Sada mi dovedite svirača.” I dok je glazbenik svirao, siđe ruka Jahvina nada nj."},{"v":16,"t":"I on reče: “Ovako veli Jahve: 'Iskopajte u ovoj dolini mnogo jama."},{"v":17,"t":"Jer ovako veli Jahve: nećete osjetiti vjetra niti ćete vidjeti dažda, a ova će se dolina napuniti vodom. I pit ćete vi, vaš marva i vaša stoka.'"},{"v":18,"t":"Ali to još nije ništa u očima Jahve: on će predati Moab u vaše ruke."},{"v":19,"t":"Vi ćete zauzeti sve utvrđene gradove, posjeći sve plodno drveće, zatrpati sve izvore i opustošiti najbolja polja: kamenjem ćete ih zasijati.”"},{"v":20,"t":"I doista, ujutro, u vrijeme kad se prinosi žrtva, dođe voda od Edoma i preplavi svu okolinu."},{"v":21,"t":"Kad su Moapci čuli da su kraljevi došli s njima ratovati, pozvaše sve koji bijahu sposobni za oružje i postaviše ih na granicu."},{"v":22,"t":"Kad su ujutro ustali i kad je sunce granulo nad onom vodom, Moapcima se sa strane voda učini crvenom kao krv."},{"v":23,"t":"I rekoše: “To je krv! Zacijelo su se kraljevi međusobno pobili i jedan drugoga pogubili. A sada: na plijen, Moapci!”"},{"v":24,"t":"Ali kad su stigli do izraelskog tabora, digoše se Izraelci i potukoše Moapce, tako te ovi pobjegoše pred njima. A Izraelci pojuriše da dotuku Moapce."},{"v":25,"t":"Razorili su im gradove, bacali svaki po kamen na najbolje njive da ih zaspu, zatrpali izvore i posjekli sve plodno drveće. Konačno, ostao je samo grad Kir Harešet; praćari su ga opkolili i tukli ga."},{"v":26,"t":"Kada je moapski kralj vidio da neće izdržati bitku, uze sa sobom sedam stotina ljudi naoružanih mačevima, pokuša se probiti i doći do kralja edomskog, ali ne uspje."},{"v":27,"t":"Tada uze svoga sina prvenca, koji ga imaše naslijediti, i prinese ga kao paljenicu na zidu. To se tako silno zgadilo Izraelcima te odoše od njih i vratiše se u svoju zemlju."}]},"4":{"hr":[{"v":1,"t":"Žena jednoga od proročkih sinova zamoli Elizeja ovako: “Tvoj sluga, moj muž, umro je; a znaš da se tvoj sluga bojao Jahve. Sada je došao vjerovnik da mi uzme oba sina i učini ih svojim robovima.”"},{"v":2,"t":"Elizej joj reče: “Što ti mogu učiniti! Reci mi što imaš u kući?” Ona odgovori: “Tvoja sluškinja nema ništa u kući, osim vrča ulja.”"},{"v":3,"t":"Tada joj reče: “Idi i posudi od svih svojih susjeda praznih sudova, ali neka ih ne bude premalo!"},{"v":4,"t":"Zatim se vrati kući, zatvori vrata za sobom i za svojim sinovima i nalijevaj ulje u sve te sudove i pune stavljaj na stranu.”"},{"v":5,"t":"I ode ona od njega, zatvori vrata za sobom i za svojim sinovima. Oni su joj dodavali sudove, a ona ih punila."},{"v":6,"t":"I kad se sudovi napuniše, reče ona svome sinu: “Dodaj mi još jedan sud!” Ali joj on odgovori: “Nema više sudova.” I ulje stade."},{"v":7,"t":"Ona ode i kaza čovjeku Božjem, a on joj reče: “Idi, prodaj ulje i podmiri svoj dug, a od ostatka živjet ćeš ti i tvoji sinovi!”"},{"v":8,"t":"Jednoga je dana Elizej prolazio kroza Šunam. A živjela ondje ugledna žena i ona ga pozva k stolu. Odonda, kad god prolazaše onuda, uvratio bi se k njoj na jelo."},{"v":9,"t":"Ona reče svome mužu: “Evo, znam i vidim da je svet onaj čovjek Božji što prolazi ovuda."},{"v":10,"t":"Načinimo mu sobicu na krovu, stavimo mu ondje postelju, stol, stolicu i svjetiljku: kad dođe k nama, povući će se onamo.”"},{"v":11,"t":"Jednoga dana dođe on onamo, povuče se u gornju sobu i počinu ondje."},{"v":12,"t":"Reče zatim svome momku Gehaziju: “Pozovi tu Šunamku!” On je pozva te ona stade preda nj."},{"v":13,"t":"I još mu reče: “Kaži joj: 'Lijepo se brineš za nas. Što možemo učiniti za te? Treba li reći riječ za te kralju ili vojskovođi?'” Ali ona odgovori: “Ja živim usred svoga naroda.”"},{"v":14,"t":"On nastavi: “Dakle, što da učinimo za nju?” Gehazi odgovori: “Eto, nema sina, a muž joj je vremešan.”"},{"v":15,"t":"A on reče: “Pozovi je!” Pozva je, a ona stade kod ulaza."},{"v":16,"t":"“Dogodine u ovo doba”, reče joj, “zagrlit ćeš sina u naručju.” A ona reče: “Ne, gospodaru moj, ne varaj službenice svoje!”"},{"v":17,"t":"Ali je žena doista zatrudnjela i rodila je sina druge godine u ono doba, kako joj je rekao Elizej."},{"v":18,"t":"Dječak je rastao. Jednoga dana ode ocu kod žetelaca."},{"v":19,"t":"I potuži se ocu: “Jao, glava, glava moja!” A otac zapovjedi jednom momku da ga odnese majci."},{"v":20,"t":"On ga uze i odvede ga njegovoj majci. Na njenim je koljenima ostao do podne i onda umrije."},{"v":21,"t":"Ona tada ode gore i položi ga u postelju Božjega čovjeka. Izišla je zatim i zaključala vrata."},{"v":22,"t":"Potom je pozvala svoga muža i rekla: “Pošalji mi jednoga od momaka i jednu magaricu; otrčat ću do čovjeka Božjeg i vratit ću se.”"},{"v":23,"t":"On je upita: “Zašto da danas pođeš k njemu? Nije ni mlađak niti je subota.” Ali ona odgovori: “Ostaj u miru!”"},{"v":24,"t":"Pošto joj je momak osamario magaricu, ona će mu: “Povedi i pođi! Ne zadržavaj me na putu, osim ako ti naredim.”"},{"v":25,"t":"Ode ona i dođe k čovjeku Božjem, na goru Karmel. Kada je čovjek Božji ugleda izdaleka, reče svome momku Gehaziju: “Evo one Šunamke."},{"v":26,"t":"Otrči pred nju i pitaj je: 'Kako si? Je li ti muž dobro? Je li ti dijete zdravo?'” Ona odgovori: “Zdravi smo.”"},{"v":27,"t":"Kada je stigla do čovjeka Božjega na gori, obujmi mu noge. Gehazi pristupi da je odmakne, ali mu čovjek Božji reče: “Pusti je jer joj je duša ojađena. Jahve mi krije, nije mi ništa objavio.”"},{"v":28,"t":"A ona reče: “Zar sam ja tražila sina od svoga gospodara? Nisam li ti govorila da me ne zavaravaš?”"},{"v":29,"t":"On tada reče Gehaziju: “Opaši se, uzmi u ruku moj štap pa idi! Ako koga susretneš, ne pozdravljaj ga; ako te tko pozdravi, ne odzdravljaj mu. Moj štap položi na dječaka.”"},{"v":30,"t":"Ali dječakova majka reče: “Života mi Jahvina i tvoga, neću te ostaviti!” On tada ustade i pođe za njom."},{"v":31,"t":"Gehazi je otišao prije njih i položio štap na dječaka, ali ne bješe ni glasa ni odziva. Vrati se on pred Elizeja i javi mu: “Dječak se nije probudio.”"},{"v":32,"t":"Elizej uđe u kuću i nađe dječaka gdje mrtav leži na njegovoj postelji."},{"v":33,"t":"Ušavši, zatvori vrata za sobom i pomoli se Jahvi."},{"v":34,"t":"Zatim se pope na postelju, leže na dječaka, položi svoja usta na njegova usta, svoje oči na njegove oči, svoje ruke na njegove ruke; disao je nad njim te se ugrijalo tijelo dječakovo."},{"v":35,"t":"Potom ustade i prošeta se po kući tamo-amo, zatim se opet pope i disaše nad njim. A dječak tada kihnu sedam puta i otvori oči."},{"v":36,"t":"I zovnu Elizej Gehazija i reče: “Pozovi tu Šunamku.” On je pozva. Kad je stigla preda nj, reče joj: “Uzmi svoga sina.”"},{"v":37,"t":"Ona, ušavši, pade mu pred noge i pokloni se do zemlje. Zatim uze svoga sina te iziđe."},{"v":38,"t":"Elizej se vrati u Gilgal, a bijaše glad u zemlji. I kad su proročki sinovi sjedili pred njim, reče svome momku: “Stavi veliki lonac na vatru i skuhaj jelo sinovima proročkim.”"},{"v":39,"t":"Jedan od njih ode u polje da nabere zelja, ali nađe divlju povijušu i nabra s nje punu haljinu gorkih plodova. Vrati se i nareza ih u lonac, jer nije znao kakvi su."},{"v":40,"t":"Usuše ljudima da jedu. Ali kad su počeli jesti, povikaše: “Čovječe Božji! Smrt je u loncu!” I nisu mogli jesti."},{"v":41,"t":"Tada će Elizej: “Donesite brašna!” I baci ga u lonac i reče: “Uspite ljudima neka jedu!” I ništa više nije bilo štetno u loncu."},{"v":42,"t":"Neki čovjek došao iz Baal Šališe i donio čovjeku Božjem kruh od prvina, dvadeset ječmenih hljebova i kaše u torbi. A on zapovjedi: “Daj ljudima neka jedu!”"},{"v":43,"t":"Ali njegov momak odgovori: “Kako to mogu postaviti pred stotinu ljudi?” On odgovori: “Podaj ljudima i neka jedu, jer ovako veli Jahve: 'Jest će i preostat će.'”"},{"v":44,"t":"I postavi on pred njih. I jedoše i još preosta, prema riječi Jahvinoj."}]},"5":{"hr":[{"v":1,"t":"Naaman, vojskovođa aramskoga kralja, bijaše ugledan čovjek i poštovan pred svojim gospodarom, jer je po njemu Jahve dao pobjedu Aramejcima. Ali taj vrsni ratnik bješe gubav."},{"v":2,"t":"Jednom su Aramejci otišli u pljačku i na području izraelskom zarobili mladu djevojku, koja je zatim služila ženi Naamanovoj."},{"v":3,"t":"Ona reče svojoj gospodarici: “Ah, kad bi se samo moj gospodar obratio proroku koji je u Samariji! On bi ga zacijelo oslobodio gube!”"},{"v":4,"t":"Naaman ode i obavijesti svoga gospodara: “Tako je i tako rekla djevojka koja je došla iz zemlje izraelske.”"},{"v":5,"t":"Aramejski kralj odgovori: “Idi onamo! Ja ću poslati pismo kralju izraelskom.” Naaman ode; ponio je deset talenata srebra; šest tisuća zlatnih šekela i deset svečanih haljina."},{"v":6,"t":"I predade kralju izraelskom pismo što kazivaše: “Uz pismo koje ti stiže, šaljem ti, evo, svoga slugu Naamana da ga izliječiš od gube.”"},{"v":7,"t":"Kad je izraelski kralj pročitao pismo, razdera haljine na sebi i reče: “Zar sam ja Bog da mogu usmrćivati i oživljavati te ga ovaj šalje k meni da ga izliječim od njegove gube? Gledajte samo kako traži povoda da me napadne!”"},{"v":8,"t":"A kad je Elizej saznao da je kralj izraelski razderao na sebi odjeću, poruči kralju: “Zašto si razderao haljine svoje? Neka onaj samo dođe k meni i neka se uvjeri da ima prorok u Izraelu.”"},{"v":9,"t":"I tako Naaman stiže sa svojim konjima i kolima i stade pred vratima Elizejeve kuće."},{"v":10,"t":"A Elizej poruči dolazniku: “Idi i okupaj se sedam puta u Jordanu i tijelo će ti opet biti čisto.”"},{"v":11,"t":"Naaman se naljuti i pođe govoreći: “Gle, ja mišljah, izići će preda me, zazvat će ime Jahve, Boga svoga, stavit će ruku na bolesno mjesto i odnijeti mi gubu."},{"v":12,"t":"Nisu li rijeke u Damasku, Abana i Parpar, bolje od svih voda izraelskih? Ne bih li se mogao u njima okupati da postanem čist?” Okrenu se i ode odande ljutit."},{"v":13,"t":"Ali mu pristupiše sluge njegove i rekoše: “Oče moj, da ti je prorok odredio i teže, zar ne bi učinio? A nekmoli kad ti je rekao: 'Okupaj se, i bit ćeš čist.'”"},{"v":14,"t":"I tako siđe, opra se sedam puta u Jordanu, prema riječi čovjeka Božjega; i tijelo mu posta opet kao u malog djeteta - očistio se!"},{"v":15,"t":"Vrati se on Elizeju sa svom svojom pratnjom, uđe, stade preda nj i reče mu: “Evo, sad znam da nema Boga na svoj zemlji, osim u Izraelu. Zato te molim, primi dar od svoga sluge.”"},{"v":16,"t":"Ali on odgovori: “Tako mi živog Jahve, komu služim, ne primam.” Naaman navaljivaše da primi, ali on ne htjede."},{"v":17,"t":"Tada Naaman reče: “Dobro, kad nećeš. Ali barem dopusti da meni, tvome sluzi, dadu ove zemlje koliko mogu ponijeti dvije mazge. Jer sluga tvoj neće više prinositi pomirnica ni klanica drugim bogovima nego samo Jahvi."},{"v":18,"t":"A Jahve neka oprosti ovo sluzi tvome: kad moj gospodar pođe u hram Rimonov da se ondje pokloni, pa se nasloni na moju ruku, onda bih se i ja poklonio u hramu Rimonovu. Neka Jahve oprosti taj čin sluzi tvome.”"},{"v":19,"t":"A on mu reče: “Idi s mirom.” I udalji se Naaman i prijeđe dio puta."},{"v":20,"t":"Gehazi, momak Elizeja, Božjega čovjeka, pomisli: “Moj je gospodar poštedio Naamana, toga Aramejca, i nije primio ništa od onoga što mu je ponudio. Tako mi živog Jahve, potrčat ću ja za njim i uzet ću štogod od njega.”"},{"v":21,"t":"I Gehazi pohitje za Naamanom. Kada ga je Naaman vidio da za njim trči, skoči mu sa svojih kola u susret i upita ga: “Je li sve dobro?”"},{"v":22,"t":"On odgovori: “Dobro je. Moj gospodar šalje me da ti kažem: upravo su stigla dva mladića iz Efrajimove gore, dvojica od proročkih sinova. Daj za njih, molim te, talenat srebra i dvoje haljine.”"},{"v":23,"t":"Naaman reče: “Uzmi, molim te, dva telenta!” I navaljivaše da uzme. I zaveza dva talenta srebra u dvije kese, i dvoje haljine, i predade ih dvojici svojih momaka da ih nose pred njim."},{"v":24,"t":"Kad je Gehazi stigao do Ofela, uze ih iz njihovih ruku i pohrani ih u kući. Zatim otpusti ljude i oni odoše."},{"v":25,"t":"Kad je došao, stao je pred svoga gospodara. Elizej ga upita “Odakle, Gehazi?” On odgovori: “Tvoj sluga nije nikamo odlazio.”"},{"v":26,"t":"Ali Elizej reče: “Nije li Duh moj bio s tobom kad je netko sišao sa svojih kola te izišao preda te? Sad si primio srebro, pa možeš kupiti maslinike, vinograde, sitno i krupno blago, sluge i sluškinje."},{"v":27,"t":"Ali će se guba Naamanova prilijepiti za te i za tvoje potomstvo zauvijek.” I Gehazi se udalji od njega, bijel od gube kao od snijega."}]},"6":{"hr":[{"v":1,"t":"Proročki sinovi rekoše Elizeju: “Gle, tijesan nam je prostor u tebe."},{"v":2,"t":"Nego da odemo do Jordana, pa da svaki ondje uzmemo po brvno i načinimo sebi ondje prebivalište.” On odgovori: “Idite.”"},{"v":3,"t":"Jedan od njih reče mu: “Udostoj se poći sa svojim slugama.” On odgovori: “Hoću.”"},{"v":4,"t":"I pođe s njima. Kad su stigli do Jordana, uzeše sjeći drva."},{"v":5,"t":"A dok je jedan od njih tesao gredu, pade mu sjekira u vodu i on povika: “Jao, gospodaru! I još je bila posuđena!”"},{"v":6,"t":"A čovjek Božji upita ga: “Gdje je pala?” Onaj mu pokaza mjesto. Tada on odsiječe komad drveta, baci ga na ono mjesto i učini da sjekira ispliva."},{"v":7,"t":"I reče: “Izvadi je!” I čovjek pruži ruku te je uze."},{"v":8,"t":"Aramejski kralj bio u ratu s Izraelom. Posavjetovao se sa svojim časnicima i rekao: “Podignite šatore na tom mjestu.”"},{"v":9,"t":"Ali Elizej poruči izraelskom kralju: “Čuvaj se onoga mjesta jer su se Aramejci ondje utaborili.”"},{"v":10,"t":"I kralj izraelski upozori ljude na mjesto za koje mu je rekao čovjek Božji. On je upozoravao i kralj se čuvao; a bilo je to više puta."},{"v":11,"t":"Srce aramejskog kralja uznemiri se zbog toga, pa on pozva svoje časnike te ih upita: “Nećete li mi reći tko od naših drži s kraljem Izraelovim?”"},{"v":12,"t":"Jedan od časnika odgovori: “Ne, gospodaru kralju; Elizej, prorok Izraelov, otkriva izraelskom kralju riječi koje kazuješ u svojoj spavaonici.”"},{"v":13,"t":"On reče: “Idite i pogledajte gdje je, pa ću već poslati da ga uhvate.” I javiše mu: “Eno ga u Dotanu.”"},{"v":14,"t":"Tada kralj posla onamo konje, kola i jake čete. Oni stigoše noću i opkoliše grad."},{"v":15,"t":"Ujutro, ustavši, čovjek Božji iziđe, a to oko grada stoji vojska s konjima i kolima! Njegov mu momak reče: “Ah, gospodaru moj, što nam je činiti?”"},{"v":16,"t":"A on odgovori: “Ne boj se jer ih ima više s nama nego s njima.”"},{"v":17,"t":"I Elizej se pomoli ovako: “Jahve, otvori mu oči da vidi!” I Jahve otvori oči momku i on vidje: gora oko Elizeja sva prekrivena ognjenim konjima i kolima!"},{"v":18,"t":"Kad su Aramejci sišli prema njemu, Elizej se ovako pomoli Jahvi: “Udari sljepoćom ove ljude!” I na riječ Elizejevu udari ih sljepoćom."},{"v":19,"t":"Elizej im reče: “Nije ovo put i nije ovo grad. Pođite za mnom, ja ću vas odvesti čovjeku koga tražite.” Ali ih odvede u Samariju."},{"v":20,"t":"Kad su ulazili u Samariju, Elizej reče: “Jahve, otvori ovima oči da progledaju.” Jahve im otvori oči i oni vidješe da su usred Samarije!"},{"v":21,"t":"Kad ih vidje kralj Izraela, reče Elizeju: “Treba li ih poubijati, oče moj?”"},{"v":22,"t":"A on odgovori: “Nemoj ih ubiti. Zar ćeš ubiti one koje nisi zarobio svojim lukom i mačem? Ponudi im kruha i vode; neka jedu i piju i neka se vrate svome gospodaru.”"},{"v":23,"t":"Kralj im priredi veliku gozbu. Pošto su jeli i pili, otpusti ih. I vratiše se svome gospodaru. I tako aramejski pljačkaši nisu više zalazili na izraelsko tlo."},{"v":24,"t":"Dogodi se poslije toga te aramejski kralj Ben-Hadad skupi svu svoju vojsku i uzađe i opkoli Samariju."},{"v":25,"t":"I nasta velika glad u Samariji, a opsada potraja toliko da je magareća glava stajala osamdeset šekela srebra, a četvrt kaba golubinje nečisti pet šekela srebra."},{"v":26,"t":"Kada je kralj prolazio po zidinama, neka mu žena vikne: “Pomozi, gospodaru kralju!”"},{"v":27,"t":"On odgovori: “Neka ti pomogne Jahve! Kako ću ti ja pomoći? Nečim s gumna ili iz tijeska?”"},{"v":28,"t":"Još joj kralj reče: “Što ti je?” Ona odgovori: “Ova mi je žena rekla: 'Daj svoga sina da ga pojedemo danas, a sutra ćemo pojesti moga!'"},{"v":29,"t":"Skuhale smo moga sina i pojele ga. A sutradan rekoh joj: 'Daj svoga sina da ga pojedemo.' Ali je ona sakrila svoga sina.”"},{"v":30,"t":"Kada je kralj čuo riječi te žene, razdrije na sebi haljine. I kad je išao po zidinama, narod vidje da mu je na tijelu kostrijet."},{"v":31,"t":"I reče tada kralj: “Neka mi Bog učini ovo zlo i doda drugo ako glava Elizeja, sina Šafatova, ostane danas na njegovim ramenima!”"},{"v":32,"t":"Elizej sjedio u svojoj kući i starješine sjedile s njim. Kralj je ispred sebe poslao glasnika, ali Elizej reče starješinama, prije nego što je glasnik stigao do njega: “Vidite li da je onaj krvnički sin naredio da mi skinu glavu? Pazite: kada glasnik stigne, zatvorite vrata i odbijte ga od vrata. Ne čuje li se topot koraka njegova gospodara za njim?”"},{"v":33,"t":"Dok im je još govorio, kralj stupi preda nj i reče mu: “Ova je nevolja, gle, od Jahve! Što da još očekujem od Jahve?”"}]},"7":{"hr":[{"v":1,"t":"Elizej reče tada: “Čuj riječ Jahvinu! Ovako veli Jahve: 'Sutra će u ovo doba na vratima Samarije biti mjera finoga brašna za šekel, a dvije mjere ječmenog brašna za šekel.'”"},{"v":2,"t":"Dvorjanik, o čiju se ruku kralj oslanjao, odgovori čovjeku Božjemu: “I kad bi Jahve načinio okna na nebu, bi li to moglo biti?” A Elizej odgovori: “Vidjet ćeš svojim očima, ali nećeš jesti.”"},{"v":3,"t":"A pred gradskim vratima bijahu četiri gubavca; rekoše oni jedan drugome: “Zašto stojimo ovdje i očekujemo smrt?"},{"v":4,"t":"Ako odlučimo ući u grad, glad je u gradu te ćemo ondje umrijeti; ako ostanemo ovdje, opet ćemo umrijeti. Hajde! Pobjegnimo i prijeđimo u aramejski tabor: ako nas ostave na životu, živjet ćemo; ako nas ubiju, pa dobro: umrijet ćemo!”"},{"v":5,"t":"U sumračje, ustavši, krenuše odande u aramejski tabor. Stigoše do ruba tabora, i gle - ondje nikoga!"},{"v":6,"t":"Jer je Jahve učinio te se u taboru aramejskom čula buka kola i konja, buka goleme vojske. I govorili su među sobom: “Eto, kralj Izraela najmio je protiv nas kraljeve hetitske i kraljeve egipatske da krenu protiv nas.”"},{"v":7,"t":"Digli su se i pobjegli u sumraku: ostavili su svoje šatore, konje i magarce, sav tabor kakav bijaše. Pobjegli su da iznesu živu glavu."},{"v":8,"t":"Kad su gubavci, dakle, došli do ruba tabora, uvukoše se u jedan šator. Pošto su se najeli i napili, uzeše odande srebro, zlato i haljine pa odoše da ih sakriju. Vratiše se onda pa uđoše u drugi šator: uzeše plijen iz njega te odoše i sakriše ga."},{"v":9,"t":"Rekoše tada jedan drugome: “Ne smijemo tako raditi. Današnji je dan pun dobrih vijesti, a mi šutimo. Ako dočekamo jutro, bit ćemo krivi. Zato pođimo! Javimo dvoru novost.”"},{"v":10,"t":"I vratiše se, pozvaše gradsku stražu i javiše: “Otišli smo u tabor aramejski, a ondje nigdje čovjeka ni ljudskoga glasa; samo konji privezani i magarci, a šatori ostavljeni kakvi jesu.”"},{"v":11,"t":"Stražari viknuše i dojaviše u unutrašnjost dvora."},{"v":12,"t":"Kralj ustade noću i reče svojim časnicima: “Ja ću vam objasniti što su nam učinili Aramejci. Kako znaju da smo gladni, izišli su iz tabora i sakrili se u polju, misleći: već će oni izići iz grada, a mi ćemo ih žive pohvatati i ući u grad.”"},{"v":13,"t":"A jedan između njegovih časnika odgovori: “Neka se uzme ipak pet od preostalih konja. S njima će biti kao sa svim mnoštvom Izraelovim koje je ovdje preostalo. Pošaljimo ih pa ćemo vidjeti.”"},{"v":14,"t":"I uzeše dva konja kolska i kralj posla ljude za aramejskim taborom govoreći: “Idite, izvidite!”"},{"v":15,"t":"Išli su za njima do Jordana; put bijaše sav prekriven haljinama i stvarima koje su Aramejci pobacali u bijegu. Glasnici se vratiše i obavijestiše kralja."},{"v":16,"t":"I narod iziđe i uze pljačkati aramejski tabor: i bijaše mjera finoga brašna za šekel, a dvije mjere ječmenoga za jedan šekel, prema riječi Jahvinoj."},{"v":17,"t":"Kralj je postavio na gradska vrata onoga dvorjanika o čiju se ruku oslanjao; a narod ga izgazi na vratima i on umrije, prema riječi što ju je rekao Božji čovjek kad mu kralj bijaše došao."},{"v":18,"t":"Dogodilo se kako je čovjek Božji rekao kralju: “Sutra u ovo doba na vratima Samarije bit će dvije mjere ječmenoga brašna za šekel i mjera finoga brašna za šekel.”"},{"v":19,"t":"Dvorjanik je odgovorio Elizeju: “Pa da Jahve načini i okna na nebu, bi li moglo biti što kažeš?” Elizej mu je odgovorio: “Vidjet ćeš svojim očima, ali nećeš jesti.”"},{"v":20,"t":"I doista, tako mu se dogodilo: izgazio ga narod na vratima te on umrije."}]},"8":{"hr":[{"v":1,"t":"Elizej bijaše savjetovao ženi kojoj je oživio sina: “Ustani, pođi sa svojom obitelji i skloni se kao tuđinka bilo kamo, jer je Jahve pustio glad; već je došla u zemlju za sedam godina.”"},{"v":2,"t":"Žena usta i učini kako joj je rekao čovjek Božji: otišla je, ona i njena obitelj, i ostala sedam godina u zemlji filistejskoj."},{"v":3,"t":"Na kraju sedme godine žena se vrati iz zemlje filistejske i ode kralju da zatraži svoju kuću i njivu."},{"v":4,"t":"Upravo je kralj razgovarao s Gehazijem, momkom Božjega čovjeka. Govorio mu je: “Pripovijedaj mi o svim velikim djelima koja je Elizej učinio.”"},{"v":5,"t":"I kad je pripovijedao kralju o uskrisenju djeteta, eto žene kojoj je Elizej oživio sina; ona se obrati kralju radi svoje kuće i njive. A Gezahi reče: “Gospodaru kralju, evo one žene i evo njena sina koga je Elizej oživio.”"},{"v":6,"t":"Kralj upita ženu i ona mu sve pripovjedi. Tada joj kralj dade jednoga slugu, komu naredi: “Neka joj se vrati sve što je njeno i svi prihodi od njive od dana kada je ostavila zemlju do danas!”"},{"v":7,"t":"Elizej dođe u Damask. Ben-Hadad, kralj aramejski, bijaše obolio. Odmah mu javiše: “Božji čovjek došao ovamo.”"},{"v":8,"t":"Tada reče kralj Hazaelu: “Uzmi sa sobom dar pa idi pred Božjeg čovjeka. I preko njega se posavjetuj s Jahvom da bi saznao hoću li se izliječiti od ove bolesti.”"},{"v":9,"t":"Hazael ode pred Elizeja i donese mu u dar što bijaše od ponajboljeg u Damasku, sve to natovareno na četrdeset deva. Dođe on i stade preda nj i reče: “Tvoj sin Ben-Hadad, kralj aramejski, šalje me k tebi i pita hoće li ozdraviti od one bolesti.”"},{"v":10,"t":"Elizej mu odgovori: “Idi i reci mu: 'Ozdravit ćeš, dakako!' Ali mi je Jahve pokazao da će umrijeti.”"},{"v":11,"t":"I čovjek Božji uprije pogled preda se, smeten, i zaplaka."},{"v":12,"t":"Hazael reče: “Zašto plačeš, moj gospodaru?” Elizej odgovori: “Zato što znam sva zla koja ćeš ti učiniti Izraelcima: spalit ćeš im utvrde, mačem ćeš poubijati njihove ratnike, njihovu ćeš djecu satirati, a trudne žene parati.”"},{"v":13,"t":"Hazael reče: “Ali što je tvoj sluga? Zar je pas da učini tako strašne stvari?” Elizej odgovori: “U jednoj Jahvinoj objavi vidio sam tebe kao kralja aramejskog.”"},{"v":14,"t":"Hazael ode od Elizeja i vrati se svome gospodaru, koji ga upita: “Što ti je rekao Elizej?” On odgovori: “Rekao mi je da ćeš ozdraviti.”"},{"v":15,"t":"Ali sutradan uze pokrivač, namoči ga u vodi i pokri kralja preko lica te on umrije. A na njegovo mjesto zakralji se Hazael."},{"v":16,"t":"Pete godine kraljevanja Jorama, sina Ahabova, u Izraelu, postade judejskim kraljem Joram, sin Jošafatov."},{"v":17,"t":"Bile su mu trideset i dvije godine kad se zakraljio, a kraljevao je osam godina u Jeruzalemu."},{"v":18,"t":"Živio je poput izraelskih kraljeva, kao i dom Ahabov, jer mu je kći Ahabova bila žena; radio je što je zlo u Jahvinim očima."},{"v":19,"t":"Ipak Jahve ne htjede razoriti Judeje zbog sluge svoga Davida, zato što mu obeća da će dati svjetiljku njemu i njegovim sinovima zauvijek."},{"v":20,"t":"U njegovo se vrijeme Edomci odmetnuše ispod judejske vlasti i postaviše sebi kralja."},{"v":21,"t":"Joram ode u Seir i s njim sva bojna kola. Diže se noću i pobi Edomce koji su bili opkolili njega i zapovjednike bojnih kola. Narod pobježe u svoje šatore."},{"v":22,"t":"Ipak su se Edomci oslobodili ispod judejske vlasti sve do danas. U isto se doba odmetnu i Libna."},{"v":23,"t":"Ostala povijest Jorama, sve što je učinio, zar to nije zapisano u knjizi Ljetopisa kraljeva judejskih?"},{"v":24,"t":"Joram počinu kraj svojih otaca i bi pokopan k svojim ocima u Davidovu gradu. Njegov sin Ahazja zakralji se mjesto njega."},{"v":25,"t":"Dvanaeste godine Jorama, sina Ahabova, kralja Izraela, postade judejskim kraljem Ahazja, sin Joramov."},{"v":26,"t":"Ahazji bijahu dvadeset i dvije godine kad se zakraljio, a kraljevao je godinu dana u Jeruzalemu. Mati mu se zvala Atalija, a bila je kći izraelskog kralja Omrija."},{"v":27,"t":"I on je hodio putem obitelji Ahabove i činio je zlo u očima Jahvinim, kao i obitelj Ahabova, jer je s njom bio u rodu."},{"v":28,"t":"On je pošao s Joramom, sinom Ahabovim, u Ramot Gilead u boj protiv Hazaela, aramskog kralja."},{"v":29,"t":"Kralj Joram vratio se u Jizreel da se liječi od rana što mu ih zadadoše u Rami kad se borio s aramejskim kraljem Hazaelom. Joramov sin Ahazja, judejski kralj, sišao je u Jizreel da posjeti Ahabova sina Jorama jer se Joram razbolio."}]},"9":{"hr":[{"v":1,"t":"Prorok Elizej pozva jednoga od proročkih sinova i reče mu: “Opaši se, uzmi sa sobom ovu posudu s uljem pa idi u Ramot Gilead."},{"v":2,"t":"Kad onamo stigneš, potraži Jehua, sina Jošafatova, sina Nimšijeva. Kad ga nađeš, izvedi ga između njegovih drugova i uvedi ga u pokrajnju sobu."},{"v":3,"t":"I uzmi posudu s uljem, izlij mu je na glavu i reci: 'Ovako veli Jahve: Pomazao sam te za kralja izraelskoga.' Zatim otvori vrata i bježi, ne oklijevaj.”"},{"v":4,"t":"Tada mladi prorok ode u Ramot Gilead."},{"v":5,"t":"Kad je stigao, zapovjednici vojske upravo su sjedili na okupu. On reče: “Imam ti riječ reći, zapovjedniče!” Jehu upita: “Komu od nas?” On odgovori: “Tebi, zapovjedniče!”"},{"v":6,"t":"Jehu tada ustade i uđe u kuću. Mladi mu čovjek izli ulje na glavu i reče mu: “Ovako veli Jahve, Bog Izraelov: 'Pomazao sam te za kralja nad Jahvinim narodom, nad Izraelom."},{"v":7,"t":"Ti ćeš pobiti obitelj Ahaba, gospodara tvoga, a ja ću osvetiti krv svojih slugu proroka i krv sviju službenika Jahvinih na Izebeli"},{"v":8,"t":"i na svoj obitelji Ahabovoj. Iskorijenit ću Ahabu sve što mokri uza zid, robove i slobodnjake u Izraelu."},{"v":9,"t":"Učinit ću s domom Ahabovim kao s domom Jeroboama, sina Nebatova, i kao s domom Baše, sina Ahijina."},{"v":10,"t":"A Izebelu će proždrijeti psi na polju jizreelskom i nitko je neće pokopati.'” - Zatim otvori vrata i pobježe."},{"v":11,"t":"Jehu iziđe k časnicima svoga gospodara. Oni ga upitaše: “Je li sve u miru? Zašto je ta budala dolazila k tebi?” On im odgovori: “Znate čovjeka i besjedu njegovu.”"},{"v":12,"t":"Oni rekoše: “Ne znamo! Kazuj nam!” On im reče: “Govorio mi je tako i tako i rekao mi: 'Ovako veli Jahve: Pomazao sam te za kralja nad Izraelom.'”"},{"v":13,"t":"Odmah oni uzeše svoje ogrtače i prostriješe ih pred njim po stepenicama, zatrubiše u rogove i povikaše: “Jehu je kralj!”"},{"v":14,"t":"Tako Jehu, sin Jošafata, sina Nimšijeva, skova urotu protiv Jorama - Joram je tada branio Ramot Gilead sa svim Izraelcima protiv Hazaela, aramejskog kralja."},{"v":15,"t":"Ali se kralj Joram vratio u Jizreel da liječi rane koje su mu zadali Aramejci u boju s Hazaelom, aramejskim kraljem. - I reče Jehu: “Ako vam je po volji, neka nitko ne utekne iz grada da odnese vijest u Jizreel.”"},{"v":16,"t":"Jehu se tada pope na kola i ode prema Jizreelu, jer je Joram ondje bolovao, i Ahazja, kralj judejski, došao ga posjetiti."},{"v":17,"t":"Stražar koji je stajao na kuli u Jizreelu, videći da dolazi Jehuova četa, javi: “Vidim nekakvu četu.” Joram naredi: “Uzmi konjanika i pošalji ga pred njih da upita: je li sve s mirom.”"},{"v":18,"t":"Ode konjanik preda nj i reče: “Ovako veli kralj: je li sve s mirom?” - Jehu odgovori: “Što te briga je li s mirom! Hajde za mnom.” Stražar javi: “Glasnik je stigao do njih, ali se ne vraća.”"},{"v":19,"t":"Kralj posla drugoga konjanika. Taj dođe k njima i upita: “Ovako veli kralj: je li sve s mirom?” - Jehu mu odgovori: “Što te briga je li s mirom! Hajde za mnom.”"},{"v":20,"t":"Stražar opet javi: “Došao je do njih, ali se ne vraća. A vožnja je kao vožnja Jehua, sina Nimšijeva: vozi kao mahnit!”"},{"v":21,"t":"Joram reče: “Preži!” I upregoše u njegova kola. Joram, kralj Izraela, i judejski kralj Ahazja iziđoše, svaki u svojim kolima, u susret Jehuu. Susretoše ga u polju Nabota Jizreelca."},{"v":22,"t":"Kad Joram ugleda Jehua, upita ga: “Je li sve u miru, Jehu?” Ovaj odgovori: “Kakvu miru dok traju bludništva tvoje majke Izebele i njena mnoga čaranja!”"},{"v":23,"t":"Joram okrenu i udari u bijeg govoreći Ahazji: “Izdaja, Ahazja!”"},{"v":24,"t":"Jehu se lati luka, ustrijeli Jorama među pleća: strijela mu prođe posred srca te se on sruši u kola."},{"v":25,"t":"Jehu reče svome dvorjaniku Bidkaru: “Digni ga i baci na njivu Nabota Jizreelca. Sjeti se: kad smo ja i ti jahali za njegovim ocem Ahabom, kako Jahve izreče protiv njega:"},{"v":26,"t":"'Kunem se: kako sinoć vidjeh krv Nabotovu i krv njegovih sinova,' riječ je Jahvina, 'tako ću ti vratiti isto na ovome polju,' riječ je Jahvina. Digni ga, dakle, i baci ga na to polje, prema riječi Jahvinoj.”"},{"v":27,"t":"Kada je to vidio judejski kralj Ahazja, pobježe prema Bet Haganu, ali ga je Jehu gonio i naredio: “Ubijte i njega!” Ranili su ga u kolima na brdu Guru, koje se nalazi kod Jibleama. Ali je umakao u Megido i ondje umrije."},{"v":28,"t":"Njegove su ga sluge u kolima prenijele u Jeruzalem i sahranile ga u grobnici kraj njegovih otaca, u Davidovu gradu."},{"v":29,"t":"Jedanaeste godine kraljevanja Jorama, sina Ahabova, Ahazja postade kralj nad Judejom."},{"v":30,"t":"A Jehu bijaše ušao u Jizreel. Kad je to čula Izebela, namaza oči, uresi glavu i pogleda s prozora."},{"v":31,"t":"I kad je Jehu ulazio na vrata, ona reče: “Kako je, Zimri, ubojico svoga gospodara?”"},{"v":32,"t":"Jehu okrenu lice prema prozoru i reče: “Tko je sa mnom, tko?” I dva-tri dvoranina pogledaše prema njemu."},{"v":33,"t":"On reče: “Bacite je dolje.” I oni je baciše. Njena je krv poprskala zidove i konje, koji je pogaziše."},{"v":34,"t":"Ušao je on, jeo i pio, a zatim naredio: “Pogledajte onu prokletnicu i sahranite je, jer je bila kraljevska kći.”"},{"v":35,"t":"I odoše da je sahrane, ali ne nađoše ništa od nje, osim lubanje, nogu i ruku."},{"v":36,"t":"Vratiše se i javiše, a Jehu reče: “To je riječ koju je Jahve objavio preko svoga sluge Ilije Tišbijca: 'U polju jizreelskom psi će proždrijeti Izebelino tijelo."},{"v":37,"t":"Izebelino truplo bit će kao gnoj u polju, da se neće moći kazati: Ovo je Izebela.'”"}]},"10":{"hr":[{"v":1,"t":"U Samariji bijaše sedamdeset Ahabovih sinova. Jehu napisa pismo i posla ga u Samariju zapovjednicima grada, starješinama i skrbnicima Ahabove djece. Kazivaše u njemu:"},{"v":2,"t":"“Sada, kad vam stigne ovo pismo - vi, u kojih su sinovi vašeg gospodara, koji imate kola i konje, tvrde gradove i oružje -"},{"v":3,"t":"pogledajte koji je između sinova vašeg gospodara najbolji i najdostojniji, pa ga postavite na prijestolje njegova oca i borite se za dom svoga gospodara.”"},{"v":4,"t":"Ali se oni veoma uplašiše i rekoše: “Eto, dva mu kralja nisu mogla odoljeti, kako ćemo mu mi odoljeti?”"},{"v":5,"t":"Upravitelj dvora, zapovjednik grada, starješine i skrbnici poručiše ovo Jehuu: “Mi smo tvoje sluge, činit ćemo sve što nam budeš naredio; kraljem proglašavati nećemo nikoga. Čini što misliš da je dobro.”"},{"v":6,"t":"Jehu im napisa drugo pismo i u njemu reče: “Ako ste za mene i želite me slušati, uzmite glave ljudi, sinova svoga gospodara, i potražite me sutra u ovo doba u Jizreelu.” Sedamdeset je naime kraljevih sinova bilo kod uglednih građana koji su ih odgajali."},{"v":7,"t":"I kad im je stiglo ovo pismo, uzeli su kraljeve sinove i pobili ih svih sedamdeset. Njihove su glave metnuli u košare i poslali su ih njemu u Jizreel."},{"v":8,"t":"Glasnik dođe i javi mu: “Donijeli su glave kraljevih sinova.” On reče: “Stavite ih do sutra kod ulaznih vrata, u dvije hrpe.”"},{"v":9,"t":"Ujutro iziđe, stade i reče svomu narodu: “Vi ste pravedni! Ja sam se urotio protiv svoga gospodara i ja sam ga ubio, ali tko pobi sve ove?"},{"v":10,"t":"Znajte, dakle, da nije izostala nijedna riječ koju reče Jahve o obitelji Ahabovoj; nego je Jahve izvršio sve što je rekao preko sluge svoga Ilije.”"},{"v":11,"t":"I Jehu pobi sve koji su u Jizreelu ostali iz kuće Ahabove, sve velikaše njegove, pouzdanike i svećenike njegove. Nije poštedio nikoga."},{"v":12,"t":"Potom usta Jehu i pođe u Samariju. Kad je bio na cesti kod Bet Ekeda pastirskoga,"},{"v":13,"t":"nađe braću judejskog kralja Ahazje te ih upita: “Tko ste?” Oni mu odgovoriše: “Mi smo braća Ahazjina, a silazimo da pozdravimo sinove kraljeve i sinove kraljičine.”"},{"v":14,"t":"Tada zapovjedi: “Pohvatajte ih žive!” I žive ih pohvataše i pobiše ih na studencu kod Bet Ekeda, njih četrdeset i dvojicu. Nije ostavio ni jednoga od njih."},{"v":15,"t":"Otišavši odatle, nađe Jonadaba, sina Rekabova, koji mu je dolazio u susret. On ga pozdravi i reče mu: “Je li tvoje srce iskreno prema mome, kao što je moje prema tvome srcu?” Jonadab odgovori: “Jest.” - “Ako je tako, daj mi ruku.” Jonadab mu pruži ruku i Jehu ga posadi kraj sebe na kola."},{"v":16,"t":"I reče mu: “Hodi sa mnom, divit ćeš se mojoj revnosti za Jahvu.” I odvede ga na svojim kolima."},{"v":17,"t":"Ušao je u Samariju i poubijao sve preživjele iz obitelji Ahabove u Samariji. Sve ih je iskorijenio po riječi koju Jahve bijaše rekao Iliji."},{"v":18,"t":"Jehu je sakupio sav narod i rekao mu: “Ahab je malo poštivao Baala; Jehu će ga više poštivati."},{"v":19,"t":"Sada mi pozovite sve proroke Baalove, sve njegove sluge i sve njegove svećenike, neka ni jedan ne izostane, jer ću žrtvovati veliku žrtvu Baalu. Tko izostane, izgubit će život.” Jehu je radio lukavo, da bi uništio Baalove vjernike."},{"v":20,"t":"Jehu reče: “Sazovite svečani zbor Baalu.” I sazvaše ga."},{"v":21,"t":"Jehu je nato poslao glasnike po svem Izraelu i došli su svi Baalovi vjernici: nije bilo ni jednoga da bi izostao. Skupili su se u Baalov hram, koji se ispunio od jednoga zida do drugoga."},{"v":22,"t":"Jehu reče čuvaru haljina: “Iznesi haljine svim Baalovim vjernicima.” I iznese im haljine."},{"v":23,"t":"Jehu uđe u hram Baalov s Jonadabom, sinom Rekabovim, i reče Baalovim vjernicima: “Provjerite dobro da nema ovdje među vama Jahvina sluge nego samih Baalovih vjernika.”"},{"v":24,"t":"I pođe žrtvovati klanice i paljenice. Ali je Jehu postavio vani osamdeset svojih ljudi i rekao im: “Ako koji od vas pusti da utekne i jedan od ovih ljudi što ih predajem u vaše ruke, svojim će životom platiti njegov život.”"},{"v":25,"t":"Kad je Jehu završio prinos paljenice, naredi tjelesnoj straži i dvoranima: “Uđite, pobijte ih! Nitko neka ne iziđe!” Tjelesna straža i dvorani uđoše, pobiše ih oštricom mača i prodriješe sve do svetišta Baalova hrama."},{"v":26,"t":"Iznesoše Baalov lik iz hrama i spališe ga."},{"v":27,"t":"Raskopaše žrtvenik Baalov, srušiše i hram Baalov i pretvoriše ga u jame za nečist, koje su ostale do danas."},{"v":28,"t":"Tako je Jehu istrijebio Baala iz Izraela."},{"v":29,"t":"Ali se Jehu nije okrenuo od grijeha Jeroboama, sina Nebatova, kojima je zavodio Izraela, od zlatnih telaca u Betelu i Danu."},{"v":30,"t":"Jahve je rekao Jehuu: “Zato što si dobro izvršio ono što mi je po volji i što si učinio sve što sam nosio u srcu protiv kuće Ahabove, tvoji će sinovi sve do četvrtoga koljena sjediti na prijestolju Izraelovu.”"},{"v":31,"t":"Ali Jehu nije vjerno i svim srcem svojim slijedio zakon Jahve, Boga Izraelova. Nije se odvratio od grijeha kojima je Jeroboam zavodio Izraela."},{"v":32,"t":"U ono je vrijeme Jahve počeo krnjiti zemlju izraelsku, i Hazael se tukao s Izraelcima na svom području,"},{"v":33,"t":"od Jordana prema sunčevu izlasku, u svoj zemlji Gileadu, u zemlji Gadovoj, Rubenovoj i Manašeovoj, sve od Aroera na obali Arnona, do Gileada i Bašana."},{"v":34,"t":"Ostala povijest Jehuova, sve što je učinio, sva njegova djela, zar to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":35,"t":"Počinuo je kraj svojih otaca i pokopaše ga u Samariji. Joahaz, sin njegov, zakralji se mjesto njega."},{"v":36,"t":"Jehu je vladao u Samariji nad Izraelom dvadeset i osam godina."}]},"11":{"hr":[{"v":1,"t":"Zato Ahazjina mati Atalija, vidjevši gdje joj sin poginu, ustade i posmica sav kraljevski rod."},{"v":2,"t":"Ali Jošeba, kći kralja Jorama i sestra Ahazjina, uze Ahazjina sina Joaša; ukravši ga između kraljevih sinova koje su ubijali, metnu ga s dojiljom u ložnicu. Tako ga je sakrila od Atalije te nije pogubljen."},{"v":3,"t":"Bio je sakriven u Domu Jahvinu šest godina, sve dok je zemljom vladala Atalija."},{"v":4,"t":"Sedme godine Jojada posla po satnike Karijaca i tjelesnu stražu i pozva ih k sebi u Dom Jahvin. Sklopi s njima savez, zakle ih i pokaza im kraljeva sina."},{"v":5,"t":"I reče im: “Evo što valja da učinite: trećina vas koji subotom ulazite u službu neka čuva stražu kod kraljevskoga dvora."},{"v":6,"t":"Druga trećina, ona kod Surskih vrata, i treća trećina, ona kod stražnjih stražarskih vrata, neka čuvaju stražu kod ulaza u dvor;"},{"v":7,"t":"a ostala dva vaša odreda, svi koji subotom izlaze iz službe, neka čuvaju stražu u Domu Jahvinu kod kralja."},{"v":8,"t":"Tako ćete okružiti kralja, svaki s oružjem u ruci. I tko god pokuša proći kroz vaše redove, neka bude pogubljen. Budite uz kralja kamo god pođe ili izađe.”"},{"v":9,"t":"Satnici su učinili sve kako im je naredio svećenik Jojada. Svaki je od njih uzeo svoje ljude koji subotom ulaze u službu s onima koji subotom izlaze. I svi su došli svećeniku Jojadi."},{"v":10,"t":"Svećenik dade satnicima koplja i štitove kralja Davida što su bili u Domu Jahvinu."},{"v":11,"t":"Stražari se svrstaše, s oružjem u ruci, od južne do sjeverne strane Doma i prema žrtveniku i Domu oko kralja unaokolo."},{"v":12,"t":"Tada Jojada izvede sina kraljeva, stavi mu krunu i dade mu Svjedočanstvo te ga pomaza za kralja. Pljeskali su i vikali: “Živio kralj!”"},{"v":13,"t":"Kad Atalija ču viku naroda, dođe k narodu u Dom Jahvin."},{"v":14,"t":"Pogleda bolje, kad gle, kralj, po običaju, stoji na svojem mjestu, a pred kraljem zapovjednici i svirači; sav puk klikće od radosti i trubi u trube. Tad Atalija razdrije haljine i povika: “Izdaja! Izdaja!”"},{"v":15,"t":"Svećenik Jojada naredi satnicima i vojnim zapovjednicima: “Izvedite je kroz redove i tko krene za njom pogubite ga mačem.” Još je svećenik dodao: “Nemojte je smaknuti u Domu Jahvinu.”"},{"v":16,"t":"Staviše ruke na nju; a kad je kroz Konjska vrata stigla do kraljevskog dvora, ondje je pogubiše."},{"v":17,"t":"Tada Jojada sklopi savez između Jahve, kralja i naroda da narod bude narod Jahvin."},{"v":18,"t":"Potom sav narod ode u Baalov hram i razoriše ga, porušiše žrtvenike i polomiše likove; a Baalova svećenika Matana ubiše pred žrtvenicima. A svećenik opet postavi straže kod Doma Jahvina."},{"v":19,"t":"Zatim uze satnike Karijaca, stražu i sav narod. Oni izvedoše kralja iz Doma Jahvina i uvedoše ga u dvor kroz Vrata stražarska. I Joaš sjede na kraljevsko prijestolje."},{"v":20,"t":"Sav se puk veselio i grad se smirio kad su Ataliju ubili mačem u kraljevskom dvoru."}]},"12":{"hr":[{"v":1,"t":"Joašu je bilo sedam godina kad se zakraljio."},{"v":2,"t":"Sedme godine Jehuova kraljevanja Joaš je postao kraljem i kraljevao je četrdeset godina u Jeruzalemu. Majka mu se zvala Sibja i bila je iz Beer Šebe."},{"v":3,"t":"Joaš je činio što je pravo u očima Jahve svega svog vijeka jer ga je poučavao svećenik Jojada."},{"v":4,"t":"Ali uzvišica nisu srušili i narod je svejednako prinosio žrtve i kad na uzvišicama."},{"v":5,"t":"Joaš reče svećenicima: “Sav novac od posvećenih darova što se donosi u Dom Jahvin, novac koji je nekomu nametnut procjenom i novac što ga tko od svoje volje donose u Dom Jahvin"},{"v":6,"t":"neka svećenici uzimaju svaki od svoga znanca i oni neka tim poprave Dom gdje god se nađe koje oštećenje.”"},{"v":7,"t":"Ali u dvadeset i trećoj godini kraljevanja Joaševa svećenici nisu još popravili Doma."},{"v":8,"t":"Tada kralj Joaš pozva svećenika Jojadu i druge svećenike i reče im: “Zašto ne popravljate Dom? Odsad ne smijete više sebi uzimati novac od svojih znanaca nego ga morate dati za popravak Doma.”"},{"v":9,"t":"Svećenici pristadoše da ne uzimaju novac od naroda, ali ni Doma da ne popravljaju."},{"v":10,"t":"Tada svećenik Jojada uze kovčeg, proreza rupu na zaklopcu i stavi ga uza žrtvenik, zdesna od ulaza u Dom Jahvin. Svećenici, čuvari praga, stavljali su u nj sav novac sabran u Domu Jahvinu."},{"v":11,"t":"Kad bi se vidjelo da u kovčegu ima mnogo novaca, došao bi kraljev tajnik s velikim svećenikom te bi prebrojili i zavezali novac koji se nalazio u Domu Jahvinu."},{"v":12,"t":"Prebrojeni novac uručivao se upraviteljima poslova oko popravka Doma Jahvina, a oni su isplaćivali drvodjeljama i graditeljima koji su radili u Domu Jahvinu"},{"v":13,"t":"i zidarima i klesačima kamena, i za nabavu drveta i tesanog kamena određena za popravak Doma Jahvina, ukratko: za troškove oko popravka Doma."},{"v":14,"t":"Ali u Domu Jahvinu nisu se pravile srebrne čaše, ni noževi, ni plitice, ni trube, niti bilo kakav predmet od zlata ili srebra za novac koji je darovan,"},{"v":15,"t":"nego su ga davali radnicima koje su najmili za popravak Jahvina Doma."},{"v":16,"t":"Nije se tražio obračun od ljudi kojima su predavali novac da ga daju radnicima, jer su oni radili savjesno."},{"v":17,"t":"Novac naknadnice i okajnice nije se unosio u Dom Jahvin, nego je pripao svećenicima."},{"v":18,"t":"Tada Hazael, aramejski kralj, pođe u rat protiv Gata i osvoji ga. Zatim odluči poći protiv Jeruzalema."},{"v":19,"t":"Joaš, judejski kralj, uze sve posvećene darove koje su posvetili judejski kraljevi, njegovi oci: Jošafat, Joram i Ahazja, sve što je sam prikazao i sve zlato koje se našlo u riznicima Doma Jahvina i kraljevskog dvora. Sve to posla Hazaelu, aramejskom kralju, i tako se ovaj udalji od Jeruzalema."},{"v":20,"t":"Ostala povijest Joaševa i sve što je učinio, zar sve to nije zapisano u knjizi Ljetopisa kraljeva judejskih?"},{"v":21,"t":"Njegovi časnici ustadoše i skovaše zavjeru; ubiše Joaša u Bet Milu kad je u nj silazio."},{"v":22,"t":"Njegovi časnici Jozakar, sin Šimatov, i Jozabad, sin Šomerov, zadaše mu smrtni udarac. Pokopali su ga kraj njegovih otaca u Davidovu gradu, a njegov sin Amasja zakralji se mjesto njega."}]},"13":{"hr":[{"v":1,"t":"Dvadeset i treće godine kraljevanja judejskog kralja Joaša, sina Ahazjina, postade Joahaz, sin Jehuov, izraelskim kraljem u Samariji. Kraljevao je sedamnaest godina."},{"v":2,"t":"On je činio što je zlo u očima Jahvinim i poveo se za grijesima Jeroboama, sina Nebatova, koji je zavodio Izraela. Od njih nije odstupao."},{"v":3,"t":"Tada Jahve uskipje gnjevom na Izraela i predade ga u ruke aramejskog kralja Hazaela i u ruke Ben-Hadada, sina Hazaelova, za sve ono vrijeme."},{"v":4,"t":"Ali je Joahaz ublažio lice Jahvino i Jahve ga je uslišio, jer je vidio nevolju koju je aramejski kralj nanosio Izraelu."},{"v":5,"t":"Jahve je dao Izraelu izbavitelja koji ga je izbavio od ruke aramejske te su Izraelci živjeli u svojim šatorima kao i prije."},{"v":6,"t":"Ali nisu odstupali od grijeha kojim Jeroboam bijaše zaveo Izraela: ustrajali su u njemu, pa i ašere ostadoše u Samariji."},{"v":7,"t":"Jahve je ostavio Joahazu samo pedeset konjanika kao vojsku, deset bojnih kola i deset tisuća pješaka; kralj aramejski bijaše ih uništio i zgazio ih kao prah u vršidbi."},{"v":8,"t":"Ostala povijest Joahazova, sve što je učinio i poduzimao, zar sve to nija zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":9,"t":"Joahaz je počinuo sa svojim ocima i bi pokopan u Samariji, a njegov sin Joaš zakralji se mjesto njega."},{"v":10,"t":"Trideset i sedme godine kraljevanja judejskoga kralja Joaša postade Joaš, sin Joahazov, izraelskim kraljem u Samariji; kraljevao je šesnaest godina."},{"v":11,"t":"Činio je što je zlo u očima Jahvinim. Nije odstupao od grijeha Jeroboama, sina Nebatova, koji je zaveo Izraela. Za njim se poveo."},{"v":12,"t":"Ostala povijest Joaševa, sve što je učinio, junaštva njegova, kako je ratovao s Amasjom, judejskim kraljem, zar sve to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":13,"t":"Joaš je počinuo sa svojim ocima, a Jeroboam se popeo na njegovo prijestolje. Joaša pokopaše u Samariji uz izraelske kraljeve."},{"v":14,"t":"Kad se Elizej razbolio od bolesti od koje mu valjade umrijeti, dođe mu izraelski kralj Joaš, rasplaka se nad njim i reče mu: “Oče moj, oče moj! Kola Izraelova i konjanici njegovi!”"},{"v":15,"t":"Elizej mu reče: “Uzmi luk i strijele.” I on dohvati luk i strijele."},{"v":16,"t":"Elizej će tada kralju: “Nategni luk!” I on ga nateže. Elizej stavi ruke na ruke kraljeve,"},{"v":17,"t":"zatim reče: “Otvori prozor prema istoku.” I on ga otvori, a nato će Elizej: “Odapni!” I on odape, a Elizej reče: “Pobjedonosna strijela Jahvina! Pobjednička strijela nad Aramejcima! Do nogu ćeš potući Aramejce kod Afeka.”"},{"v":18,"t":"I nastavi: “Uzmi strijele!” On ih uze. Elizej tada reče kralju: “Udri o zemlju!” On udari tri puta i stade."},{"v":19,"t":"Tada se rasrdi na njega Božji čovjek i reče: “Pet ili šest puta trebalo je da udariš! Tada bi potpuno potukao Aramejce; ovako ćeš ih pobijediti samo tri puta.”"},{"v":20,"t":"Elizej zatim umrije i pokopaše ga. A pljačkaške čete Moabaca napadale zemlju svake godine."},{"v":21,"t":"Dogodilo se te su neki, sahranjujući čovjeka, opazili razbojnike: baciše mtrvaca u grob Elizejev i odoše. Mrtvac, dotakavši se Elizejevih kostiju, oživje i stade na noge."},{"v":22,"t":"Aramejski kralj Hazael ugnjetavaše Izraelce svega vijeka Joahazova."},{"v":23,"t":"Ali im se Jahve smilova i ražali se nad njima. Pogleda na njih zbog svoga Saveza koji je sklopio s Abrahamom, Izakom i Jakovom. Nije ih htio uništiti i nije ih odbacio daleko od svoga lica do danas."},{"v":24,"t":"Hazael, aramejski kralj, umrije, a njegov sin Ben-Hadad zavlada namjesto njega."},{"v":25,"t":"Tada Joaš, sin Joahazov, opet uze iz ruke Ben-Hadada, sina Hazaelova, gradove koje Hazael u ratu bijaše oteo njegovu ocu Joahazu. Joaš ga je tri puta potukao i vratio gradove Izraelove."}]},"14":{"hr":[{"v":1,"t":"Druge godine kraljevanja Joaša, sina Joahazova, nad Izraelom, postade judejskim kraljem Amasja, sin Joašev."},{"v":2,"t":"Bilo mu je dvadeset i pet godina kad se zakraljio, a kraljevao je dvadeset i devet godina u Jeruzalemu. Mati mu se zvala Joadana i bila je iz Jeruzalema."},{"v":3,"t":"Činio je što je pravo u Jahvinim očima, ali ne sasvim kao praotac njegov David. U svemu je slijedio Joaša, svoga oca."},{"v":4,"t":"Ali uzvišica nije razrušio i narod je svejednako prinosio žrtve i kad na uzvišicama."},{"v":5,"t":"Kad je učvrstio kraljevstvo, smakao je one časnike koji su mu ubili oca."},{"v":6,"t":"Ali nije pogubio sinova onih ubojica, prema onome što je napisano u knjizi Zakona Mojsijeva, gdje Jahve zapovijeda: “Neka se očevi ne pogubljuju za sinove ni sinovi za očeve, nego svatko neka gine za svoj grijeh.”"},{"v":7,"t":"On je potukao Edomce u Slanoj dolini, deset tisuća njih, i u bitki je zauzeo Selu; dao joj je ime Jokteel, koje nosi do današnjega dana."},{"v":8,"t":"Tada Amasja posla glasnike izraelskom kralju Joašu, sinu Jehuova sina Joahaza, i poruči mu: “Dođi da se ogledamo!”"},{"v":9,"t":"A izraelski kralj Joaš odvrati judejskom kralju Amasji: “Libanonski je trn jedanput poslao glasnike k libanonskom cedru: 'Daj kćer mome sinu za ženu', ali su divlje zvijeri libanonske prošle i trn izgazile."},{"v":10,"t":"Potukao si Edomce, pa ti se srce uzobijestilo i tražiš slavu! Radije ostani kod kuće. Zašto izazivaš zlo i hoćeš da propadneš ti i svi Judejci s tobom?”"},{"v":11,"t":"Ali Amasja ne posluša. Izađe izraelski kralj Joaš te se ogledaše u boju on i judejski kralj Amasja u Bet Šemešu u Judeji."},{"v":12,"t":"Izraelci poraziše Judejce i oni pobjegoše svaki pod svoj šator."},{"v":13,"t":"Izraelski kralj Joaš uhvati u Bet Šemešu judejskoga kralja Amasju, sina Joaševa, sina Ahazjina, i odvede ga u Jeruzalem. Tada sruši jeruzalemski zid od Efrajimovih vrata do Ugaonih vrata, u dužini od četiri stotine lakata."},{"v":14,"t":"Uzevši sve zlato, srebro i posuđe što se nalazilo u Domu Jahvinu i u riznici kraljevskog dvora, povrh toga i taoce, vrati se u Samariju."},{"v":15,"t":"Ostala povijest Joaševa, sve što je činio i poduzimao i kako je ratovao s Amasjom, judejskim kraljem, zar sve to nije zapisano u knjizi Ljetopisa izraelskih kraljeva?"},{"v":16,"t":"Joaš je počinuo sa svojim ocima i pokopan je u Samariji uz kraljeve izraelske. Sin njegov Jeroboam zakralji se mjesto njega."},{"v":17,"t":"Amasja, sin Joašev, judejski kralj, živio je još petnaest godina poslije smrti izraelskog kralja Joaša, sina Joahazova."},{"v":18,"t":"A ostala povijest Amasjina zar nije zapisana u knjizi Ljetopisa kraljeva judejskih?"},{"v":19,"t":"Protiv njega je skovana urota u Jeruzalemu. Iako je on pobjegao u Lakiš, poslaše za njim u Lakiš ljude koji ga ondje ubiše."},{"v":20,"t":"Odande su ga prenijeli na konjima i sahranili u Jeruzalemu kraj njegovih otaca, u Davidovu gradu."},{"v":21,"t":"Tada sav judejski narod uze Azahju, komu bijaše šesnaest godina, i zakralji ga namjesto njegova oca Amasje."},{"v":22,"t":"On opet sagradi Elat povrativši ga Judeji, pošto je kralj počinuo kod svojih otaca."},{"v":23,"t":"Petnaeste godine kraljevanja judejskog kralja Amasje, sina Joaševa, postade izraelskim kraljem u Samariji Jeroboam, sin Joašev. On je kraljevao četrdeset i jednu godinu."},{"v":24,"t":"Činio je što je zlo u očima Jahvinim, nije se ostavio nijednoga grijeha Jeroboama, sina Nebatova, koji je zaveo Izraela."},{"v":25,"t":"On je dobio natrag izraelsko područje od Ulaza u Hamat do Mrtvoga mora, prema riječi koju je Jahve, Bog Izraelov, rekao preko sluge svoga Jone, sina Amitajeva, proroka iz Gat Hahefera."},{"v":26,"t":"Jer je Jahve vidio ljutu nevolju Izraelovu da više nema ni slobodnih ni robova i nikoga da pomogne Izraelu."},{"v":27,"t":"Ali Jahve nije odlučio izbrisati ispod neba ime Izraelovo: spasio ga je rukom Jeroboama, sina Joaševa."},{"v":28,"t":"Ostala povijest Jeroboama, sve što je učinio i sve što je poduzimao, kako je ratovao i kako je vratio Damask Judi i Izraelu, zar sve to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":29,"t":"Jeroboam je počinuo sa svojim ocima. Pokopali su ga u Samariji uz kraljeve izraelske, a njegov sin Zaharija zakralji se mjesto njega."}]},"15":{"hr":[{"v":1,"t":"Dvadeset i sedme godine kraljevanja Jeroboama, kralja izraelskog, postade judejskim kraljem Azarja, sin Amasjin."},{"v":2,"t":"Bilo mu je šesnaest godina kad se zakraljio, a kraljevao je pedeset i dvije godine u Jeruzalemu. Mati mu se zvala Jekolija, a bila je iz Jeruzalema."},{"v":3,"t":"Činio je što je pravo u Jahvinim očima, sasvim kao i njegov otac Amasja."},{"v":4,"t":"Samo uzvišica nije srušio i narod je svejednako prinosio žrtve i kad na uzvišicama."},{"v":5,"t":"Ali Jahve udari kralja i ostade on gubav do smrti. Stanovao je u odvojenoj kući. Kraljev sin Jotam bio upravitelj dvora i sudio je puku zemlje."},{"v":6,"t":"Ostala povijest Azarjina i sve što je učinio, zar sve to nije zapisano u knjizi Ljetopisa kraljeva judejskih?"},{"v":7,"t":"Azarja je počinuo i sahraniše ga kraj njegovih otaca u Davidovu gradu. A na njegovo se mjesto zakralji sin mu Jotam."},{"v":8,"t":"Trideset i osme godine Azarjina kraljevanja u Judeji postade izraelskim kraljem u Samariji za šest mjeseci Zaharija, sin Jeroboamov."},{"v":9,"t":"On je činio što je zlo u očima Jahvinim, kao što su činili njegovi oci; nije odstupao od grijeha Jeroboama, sina Nebatova, koji je na grijeh naveo Izraela."},{"v":10,"t":"Šalum, sin Jabešov, uroti se protiv njega; udario ga je i usmrtio u Jibleamu te se zakraljio mjesto njega."},{"v":11,"t":"Ostala povijest Zaharijina zapisana je u knjizi Ljetopisa izraelskih kraljeva."},{"v":12,"t":"Ispunila se riječ koju je Jahve rekao Jehuu: “Tvoji će sinovi sjediti na prijestolju Izraela sve do četvrtog koljena.” I tako je bilo."},{"v":13,"t":"Šalum, sin Jabešov, postade kraljem trideset i devete godine kraljevanja Uzije, judejskog kralja, i kraljevao je mjesec dana u Samariji."},{"v":14,"t":"Menahem, sin Gadijev, ode iz Tirse, uđe u Samariju te udari Šaluma, sina Jabešova, usmrti ga i zakralji se mjesto njega."},{"v":15,"t":"Ostala povijest Šalumova i urota koju je skovao, sve je zapisano u knjizi Ljetopisa kraljeva izraelskih."},{"v":16,"t":"Tada je Menahem razorio Tifnah i sve što je u njem bilo i njegovo područje od Tirse jer mu nisu otvorili vrata. Razorio ga je i rasporio sve trudnice u njemu."},{"v":17,"t":"Trideset i devete godine kraljevanja Azarje u Judeji postade Menahem, sin Gadijev, kraljem Izraela. Kraljevao je deset godina u Samariji."},{"v":18,"t":"Činio je što je zlo u očima Jahvinim; nije odstupao od grijeha Jeroboama, sina Nebatova, koji je zaveo Izraela. U njegovo vrijeme"},{"v":19,"t":"Pul, kralj Asirije, osvoji zemlju. Menahem dade Pulu tisuću talenata srebra da mu pomogne učvrstiti kraljevsku vlast u njegovim rukama."},{"v":20,"t":"Menahem ubra taj novac od Izraela, od svih imućnih ljudi, da bi ga mogao dati asirskom kralju. Po osobi je bilo pedeset šekela srebra. Tako se asirski kralj vratio i nije ondje ostao u zemlji."},{"v":21,"t":"Ostala povijest Menahema i sve što je učinio, zar sve to nije zapisano u knjizi Ljetopisa kraljeva izraelskih?"},{"v":22,"t":"Menahem je počinuo sa svojim ocima, a sin njegov Pekahja zakralji se na njegovo mjesto."},{"v":23,"t":"Pedesete godine kraljevanja judejskog kralja Azarje postade kraljem izraelskim u Samariji Pekahja, sin Menahemov. Kraljevao je dvije godine."},{"v":24,"t":"On je činio što je zlo u očima Jahvinim; nije odstupao od grijeha Jeroboama, sina Nebatova, koji je zaveo Izraela."},{"v":25,"t":"Njegov dvoranin Pekah, sin Remalijin, uroti se protiv njega i ubi ga u Samariji, u kuli kraljevskog dvora, s Argobom i Arjeom. Imao je sa sobom pedeset ljudi iz Gileada. Ubio je kralja i zakraljio se mjesto njega."},{"v":26,"t":"Ostala povijest Pekahje i sve što je učinio, sve je to zapisano u knjizi Ljetopisa izraelskih kraljeva."},{"v":27,"t":"Pedeset i druge godine kraljevanja Azarje, judejskoga kralja, postade kraljem u Samariji Pekah, sin Remalijin. Kraljevao je dvadeset godina."},{"v":28,"t":"On je činio što je zlo u očima Jahvinim; nije odstupao od grijeha Jeroboama, sina Nebatova, koji je zaveo Izraela."},{"v":29,"t":"U vrijeme izraelskog kralja Pekaha došao je asirski kralj Tiglat Pileser i zauzeo Ijon, Abel Bet Maaku, Janoah, Kedeš, Hasor, Gilead, Galileju i svu zemlju Naftalijevu. I odveo je stanovništvo u Asiriju."},{"v":30,"t":"Hošea, sin Elin, uroti se protiv Pekaha, sina Remalijina, ubi ga i zakralji mjesto njega dvadesete godine Jotama, sina Uzijina."},{"v":31,"t":"Ostala povijest Pekahova, sve što je učinio, sve je to zapisano u knjizi Ljetopisa izraelskih kraljeva."},{"v":32,"t":"Druge godine kraljevanja Pekaha, sina Remalijina, nad Izraelom, postade judejskim kraljem Jotam, sin Uzijin."},{"v":33,"t":"Bilo mu je dvadeset i pet godina kad se zakraljio, a kraljevao je šesnaest godina u Jeruzalemu. Materi mu bješe ime Jeruša, Sadokova kći."},{"v":34,"t":"Činio je što je pravo u Jahvinim očima, sasvim kao i otac mu Uzija."},{"v":35,"t":"Ali ni on nije srušio uzvišica; narod je svejednako prinosio žrtve i kad na uzvišicama. On je sagradio Gornja vrata na Domu Jahvinu."},{"v":36,"t":"Ostala povijest Jotama i sve što je učinio, zar to nije sve zapisano u knjizi Ljetopisa judejskih kraljeva?"},{"v":37,"t":"U njegove je dane Jahve počeo slati protiv Judeje aramejskog kralja Resina i Pekaha, sina Remalijina."},{"v":38,"t":"Tada Jotam počinu kod otaca i sahraniše ga u gradu njegova praoca Davida. A na njegovo se mjesto zakralji sin mu Ahaz."}]},"16":{"hr":[{"v":1,"t":"Sedamnaeste godine vladanja Pekaha, sina Remalijina, postade judejskim kraljem Ahaz, sin Jotamov."},{"v":2,"t":"Ahazu je bilo dvadeset godina kad se zakraljio, a kraljevao je šesnaest godina u Jeruzalemu, ali nije činio što je pravo u očima Jahve, Boga njegova, kao što je činio predak mu David."},{"v":3,"t":"Živio je poput izraelskih kraljeva i sam je proveo svoga sina kroz oganj po gnusnom običaju naroda što ih je Jahve protjerao pred Izraelovim sinovima."},{"v":4,"t":"Prinosio je žrtve i kad po uzvišicama i brežuljcima i pod svakim zelenim drvetom."},{"v":5,"t":"Tada aramejski kralj Resin i Pekah, sin Remalijin, kralj Izraela, pođoše u rat protiv Jeruzalema. Opsjedoše ga, ali ga ne mogoše osvojiti."},{"v":6,"t":"U to vrijeme aramejski kralj Resin vrati Elat Edomcima; protjerao je Judejce iz Elata; ušli su Edomci u njega i ondje su ostali do danas. -"},{"v":7,"t":"Tada Ahaz uputi poslanike asirskom kralju Tiglat-Pileseru da mu kažu: “Ja sam tvoj sluga i sin tvoj! Dođi i izbavi me iz ruku aramejskog kralja i kralja Izraela, koji su se digli protiv mene.”"},{"v":8,"t":"Ahaz je uzeo srebro i zlato što se nalazilo u Domu Jahvinu i u riznicama kraljevskog dvora i sve je poslao na dar asirskom kralju."},{"v":9,"t":"I posluša ga asirski kralj: otišao je na Damask i osvojio ga. Stanovništvo je odveo u sužanjstvo u Kir, a Resina je pogubio."},{"v":10,"t":"Kralj Ahaz otišao je u Damask u susret asirskom kralju Tiglat-Pileseru. I vidio je žrtvenik koji bijaše u Damasku. Tada kralj Ahaz posla svećeniku Uriji mjere žrtvenika, njegov nacrt i sve pojedinosti njegove građe."},{"v":11,"t":"Svećenik Urija sagradi žrtvenik; sve je upute što ih je kralj Ahaz uputio iz Damaska izvršio svećenik Urija prije nego što se kralj Ahaz vratio iz Damaska."},{"v":12,"t":"Pošto je kralj Ahaz stigao iz Damaska, vidio je žrtvenik, prišao mu i popeo se na nj."},{"v":13,"t":"Spalio je na žrtveniku svoju paljenicu i svoju prinosnicu, izlio svoju ljevanicu i krvlju pričesnica poškropio žrtvenik."},{"v":14,"t":"A mjedeni žrtvenik, koji bijaše pred Jahvom, maknuo je ispred Hrama, gdje je bio između novoga žrtvenika i Doma Jahvina. I postavio ga je pokraj novoga žrtvenika sa sjevera."},{"v":15,"t":"Kralj Ahaz zapovjedio je svećeniku Uriji: “Na velikom ćeš žrtveniku spaljivati jutarnju paljenicu i večernju prinosnicu, kraljevu paljenicu i njegovu prinosnicu, i paljenice, prinosnice i ljevanice svega naroda. Po njemu ćeš izlijevati svu krv paljenica i klanica. A o žrtveniku od mjedi još ću razmisliti.”"},{"v":16,"t":"Svećenik Urija učini sve što mu je naredio kralj Ahaz."},{"v":17,"t":"Kralj Ahaz skinuo je okvire s podnožja; s njih je skinuo i umivaonike. A mjedeno more skinuo je s volova koji su stajali pod njim i stavio ga na kameni pod."},{"v":18,"t":"Pred asirskim je kraljem uklonio iz Jahvina Doma Subotnji hodnik koji bijahu sagradili i vanjski kraljevski prilaz."},{"v":19,"t":"Ostala povijest Ahazova i sve što je učinio, zar to nije sve zapisano u knjizi Ljetopisa judejskih kraljeva?"},{"v":20,"t":"Ahaz je počinuo sa svojim ocima i sahranjen je u Davidovu gradu. Na njegovo se mjesto zakraljio sin mu Ezekija."}]},"17":{"hr":[{"v":1,"t":"Dvanaeste godine kraljevanja Ahaza u Judeji, postao je Hošea, sin Elin, izraelskim kraljem u Samariji. Kraljevao je devet godina."},{"v":2,"t":"On je činio što je zlo u očima Jahvinim, ali ne kao izraelski kraljevi, njegovi prethodnici."},{"v":3,"t":"Asirski kralj Salmanasar pošao je protiv Hošee, koji mu se pokorio i plaćao mu danak."},{"v":4,"t":"Ali je asirski kralj otkrio da mu Hošea sprema zavjeru: još je Hošea poslao poslanike egipatskom kralju Sou i nije platio danaka asirskom kralju kao svake godine. Tada ga asirski kralj baci u tamnicu."},{"v":5,"t":"Asirski kralj osvoji svu zemlju i krenu opsjedati Samariju. Opsjedao ju je tri godine."},{"v":6,"t":"Devete godine Hošeine vladavine zauze asirski kralj Samariju i odvede Izraelce u sužanjstvo u Asiriju. Naselio ih je u Helahu, i na Haboru, rijeci u Gozanu, i u gradovima medijskim."},{"v":7,"t":"I tako se dogodilo zato što su Izraelci sagriješili protiv Jahve, Boga svoga, koji ih je izveo iz zemlje egipatske, ispod vlasti faraona, kralja egipatskog. Štovali su druge bogove,"},{"v":8,"t":"slijedili običaje naroda što ih je Jahve protjerao pred sinovima Izraelovim, živjeli po običajima što su ih uveli kraljevi Izraelovi."},{"v":9,"t":"Izraelci i njihovi kraljevi potajno su činili neprikladna djela protiv Jahve, Boga svoga. Podigli su uzvišice u svim svojim naseljima: od stražarskih kula pa do utvrđenih gradova."},{"v":10,"t":"Podizali su stupove i ašere na svakom humku i pod svakim zelenim drvetom."},{"v":11,"t":"Ondje su, na svim uzvišicama, palili kad po običaju naroda što ih je Jahve protjerao ispred njih i činili su zla djela te izazivali gnjev Jahvin."},{"v":12,"t":"Služili su idolima, premda im Jahve bijaše rekao: “Ne činite toga!”"},{"v":13,"t":"A Jahve opominjaše Izraelce i Judejce preko svih svojih proroka i sviju vidjelaca: “Obratite se od zlog puta svoga”, govorio je, “i pokoravajte se naredbama i zapovijedima mojim prema Zakonu koji sam naložio ocima vašim i prema svemu što sam vam objavio preko slugu svojih - proroka.”"},{"v":14,"t":"Ali oni nisu poslušali nego su ostali tvrdovrati kao i njihovi oci, koji nisu vjerovali u Jahvu, Boga svoga."},{"v":15,"t":"Prezreli su njegove zakone i Savez koji je sklopio s njihovim ocima i opomene njegove koje im je upućivao. Težili su za ispraznošću, pa su i sami postali isprazni slijedeći narode oko sebe, premda im je Jahve zapovjedio da ne čine kao oni."},{"v":16,"t":"Odbacili su sve zapovijedi Jahve, Boga svoga, i načinili su sebi salivene idole, dva teleta. Podigli su ašere, klanjali se svoj vojsci nebeskoj i služili Baalu."},{"v":17,"t":"Provodili su svoje sinove i kćeri kroz oganj, odavali se vračanju i gatanju, čineći tako zlo u očima Jahvinim i razjarujući ga."},{"v":18,"t":"Tada se Jahve razgnjevi na Izraela i odbaci ga ispred svoga lica. Ostalo je samo pleme Judino."},{"v":19,"t":"Ali ni pleme Judino nije držalo zapovijedi Jahve, Boga svoga, i slijedilo je običaje kojih su se držali Izraelci."},{"v":20,"t":"I Jahve odbaci sav rod Izraela, ponizi ga i predade ga pljačkašima, dok ih konačno ne odbaci daleko od svoga lica."},{"v":21,"t":"On je, konačno, otrgnuo Izraelce od kuće Davidove, a Izrael je proglasio kraljem Jeroboama, sina Nebatova. Jeroboam je odvratio Izraela od Jahve i naveo ih na veliku grehotu."},{"v":22,"t":"Izraelci su slijedili svaki grijeh koji je Jeroboam počinio i od njega se nisu odvraćali,"},{"v":23,"t":"dok konačno Jahve nije odbacio Izraela ispred svoga lica, kako to bijaše objavio po svojim slugama, prorocima. Odveo je Izraelce iz njihove zemlje u sužanjstvo u Asiriju, gdje su do današnjega dana."},{"v":24,"t":"Asirski je kralj doveo ljude iz Babilona, iz Kute, iz Ave, Hamata i iz Sefarvajima, i naselio ih u gradovima Samarije mjesto Izraelaca. Oni su zaposjeli Samariju i nastanili se u gradovima njezinim."},{"v":25,"t":"U vrijeme naseljavanja u zemlju nisu štovali Jahve i on je poslao protiv njih lavove da ih rastrgaju."},{"v":26,"t":"Zato su rekli asirskom kralju: “Narodi koje si preselio da ih nastaniš u gradovima Samarije ne znaju kako valja štovati Boga ove zemlje i on je na njih poslao lavove, koji ih usmrćuju, jer ti narodi ne poznaju bogoštovlja ove zemlje.”"},{"v":27,"t":"Tada je asirski kralj izdao ovu zapovijed: “Neka ide onamo jedan od svećenika koje sam odande doveo u sužanjstvo; neka ide, neka se ondje nastani i pouči ih u štovanju Boga one zemlje.”"},{"v":28,"t":"Tako ode jedan od svećenika koji su bili odvedeni iz Samarije i nastani se u Betelu. On ih je poučio kako treba štovati Jahvu."},{"v":29,"t":"Svaki je narod imao likove svojih bogova i postavili su ih u hramove na uzvišicama koje su podigli Samarijanci, svaki narod u svojim gradovima u kojima življaše."},{"v":30,"t":"Babilonci načiniše Sukot Benota, Kušani Nergala, Hamaćani Ašimu;"},{"v":31,"t":"Avijci načiniše Nibhaza i Tartaka, a Sefarvajimci spaljivahu svoju djecu na ognju u čast Adrameleka i Anameleka, sefarvajimskih bogova."},{"v":32,"t":"Oni su štovali i Jahvu i postavili su neke između sebe za svećenike uzvišica koji su im prinosili žrtve u hramovima uzvišica."},{"v":33,"t":"Štovali su Jahvu i služili su svojim bogovima po običaju onih naroda između kojih su ih preselili."},{"v":34,"t":"Oni se još i danas drže starih običaja. Ne štuju Jahve i ne usklađuju svojih pravila i običaja sa Zakonom i zapovijedima što ih je Jahve naredio djeci Jakova komu je nadjenuo ime Izrael."},{"v":35,"t":"Jahve bijaše s njima sklopio Savez i zapovjedio im: “Ne štujte tuđih bogova niti im se klanjajte. Nemojte ih štovati niti im žrtava prinositi."},{"v":36,"t":"Samo je Jahve onaj koji vas je velikom snagom svoje ispružene ruke izveo iz zemlje egipatske; njega štujte, njemu se klanjajte i njemu žrtve prinosite."},{"v":37,"t":"Držite se pravila i običaja, zakona i naredaba koje vam je propisao da ih vjerno ispunjavate uvijek i ne štujte tuđih bogova."},{"v":38,"t":"Nemojte zaboraviti Saveza koji sam sklopio s vama i nemojte štovati drugih bogova,"},{"v":39,"t":"samo Jahvu, Boga svoga, poštujte i on će vas izbaviti iz ruke svih vaših neprijatelja.”"},{"v":40,"t":"Ali oni nisu poslušali, nego su se i dalje držali svoga starog običaja."},{"v":41,"t":"Tako su ti narodi štovali Jahvu, a služili su i svojim idolima. Njihovi sinovi i sinovi njihovih sinova čine do dana današnjega onako kako su činili njihovi oci."}]},"18":{"hr":[{"v":1,"t":"Treće godine kraljevanja Hošee, sina Elina, u Izraelu, postao je judejskim kraljem Ezekija, sin Ahazov."},{"v":2,"t":"Bilo mu je dvadeset i pet godina kad se zakraljio. Kraljevao je dvadeset i devet godina u Jeruzalemu. Materi mu je bilo ime Abija, Zaharijina kći."},{"v":3,"t":"Činio je što je pravo u očima Jahvinim, sasvim kao njegov otac David."},{"v":4,"t":"On je uklonio uzvišice, srušio je stupove, sasjekao je ašere i razbio zmiju od mjedi koju bijaše načinio Mojsije. Izraelci su joj sve do tada prinosili žrtve. Zvali su je Nehuštan."},{"v":5,"t":"Pouzdavao se u Jahvu, Boga Izraelova. Ni prije njega ni poslije njega ne bijaše mu ravna među kraljevima judejskim."},{"v":6,"t":"Prionuo je uz Jahvu i nikada se nije okrenuo od njega. Držao je sve zapovijedi što ih je Jahve dao preko Mojsija."},{"v":7,"t":"I Jahve bijaše s njim, pomagaše ga u svim njegovim pothvatima. Pobunio se protiv asirskog kralja i nije mu više bio podložan."},{"v":8,"t":"On je potukao Filistejce do Gaze, opustošio njihovo područje od stražarskih kula sve do utvrđenih gradova."},{"v":9,"t":"Četvrte godine vladavine Ezekijine, a to je bila sedma godina kraljevanja izraelskog kralja Hošee, sina Elina, napade asirski kralj Salmanasar Samariju i opsjede je."},{"v":10,"t":"Osvojio ju je nakon tri godine. Šeste godine Ezekijine vladavine, a devete godine izraelskog kralja Hošee, pala je Samarija."},{"v":11,"t":"Asirski je kralj odveo Izraelce u sužanjstvo u Asiriju i naselio ih u Halahu, na Haboru, rijeci gozanskoj, i u medijskim gradovima."},{"v":12,"t":"Bijaše to stoga što nisu poslušali glas Jahve, Boga svoga, i što su prekršili njegov Savez i sve što im je naredio Mojsije, sluga Jahvin. Nisu ništa slušali niti vršili."},{"v":13,"t":"Četrnaeste godine Ezekijina kraljevanja asirski kralj Sanherib napade utvrđene judejske gradove i osvoji ih."},{"v":14,"t":"Tada judejski kralj Ezekija poruči asirskom kralju u Lakiš: “Pogriješio sam! Obustavi svoje napade na me. Snosit ću sve što mi nametneš.” Asirski kralj zatraži od Ezekije, judejskog kralja, tri stotine talenata srebra i trideset talenata zlata."},{"v":15,"t":"I dade Ezekija sve srebro što se našlo u Domu Jahvinu i u riznicama kraljevskog dvora."},{"v":16,"t":"U to je vrijeme Ezekija obio vrata i vratnice na Svetištu Jahvinu što ih bijaše pozlatio on sam, judejski kralj Ezekija, i posla to asirskom kralju."},{"v":17,"t":"Asirski je kralj poslao iz Lakiša u Jeruzalem kralju Ezekiji vrhovnog zapovjednika vojske, velikog dvoranina i peharnika s jakom vojskom. Krenuše oni, a kad su stigli u Jeruzalem, stadoše kod vodovoda Gornjeg ribnjaka, na putu u Valjarevo polje."},{"v":18,"t":"Oni pozvaše kralja. Pred njim je izašao upravitelj dvora Elijakim, sin Hilkijin, pisar Šebna i savjetnik Joah, sin Asafov."},{"v":19,"t":"Veliki peharnik reče im: “Kažite Ezekiji: 'Ovako veli veliki kralj, kralj asirski: kakvo je to pouzdanje u koje se uzdaš?"},{"v":20,"t":"Misliš li da su prazne riječi već savjet i snaga za rat? U koga se uzdaš da si se pobunio protiv mene?"},{"v":21,"t":"Eto, oslanjaš se na Egipat, na slomljenu trsku koja probada i prodire dlan onomu tko se na nju nasloni. Takav je faraon, kralj egipatski, svima koji se uzdaju u njega.'"},{"v":22,"t":"Možda ćete mi odgovoriti: 'Uzdamo se u Jahvu, Boga svojega.' Ali nije li njemu Ezekija uklonio uzvišice i žrtvenike i zapovjedio Judejcima i Jeruzalemu: 'Samo se pred ovim žrtvenikom u Jeruzalemu klanjajte.'"},{"v":23,"t":"Hajde, okladi se s mojim gospodarom, asirskim kraljem: dat ću ti dvije tisuće konja ako mogneš naći jahače za njih!"},{"v":24,"t":"Kako ćeš onda odoljeti jednome jedinom od najmanjih slugu moga gospodara? Ali se ti uzdaš u Egipat da će ti dati kola i konjanika."},{"v":25,"t":"Naposljetku, zar sam ja mimo volju Jahvinu krenuo protiv ovoga mjesta da ga razorim? Sam mi je Jahve rekao: 'Idi na tu zemlju i razori je!'”"},{"v":26,"t":"Elijakim, Šebna i Joah rekoše velikom peharniku: “Molimo te, govori svojim slugama aramejski, jer mi razumijemo; ne govori s nama judejski da čuje narod koji je na zidinama!”"},{"v":27,"t":"Ali im veliki peharnik odgovori: “Zar me moj gospodar poslao da ovo kažem tvome gospodaru i tebi, a ne upravo onim ljudima koji sjede na zidinama, osuđeni da s vama jedu svoju nečist i piju svoju mokraću?”"},{"v":28,"t":"Tada se veliki peharnik uspravi i u sav glas povika na judejskom ove riječi: “Čujte riječ velikoga kralja, kralja asirskog!"},{"v":29,"t":"Ovako veli kralj: 'Neka vas Ezekija ne zavarava, jer vas ne može izbaviti iz moje ruke."},{"v":30,"t":"Neka vas Ezekija ne hrabri pouzdanjem u Jahvu govoreći: Jahve će nas sigurno izbaviti, ovaj grad neće pasti u ruke kralju asirskom.'"},{"v":31,"t":"Ne slušajte Ezekije, jer ovako veli asirski kralj: 'Sklopite mir sa mnom, predajte mi se, pa neka svaki od vas jede plodove iz svoga vinograda i sa svoje smokve i neka pije vode iz svojega studenca"},{"v":32,"t":"dok ne dođem i ne odvedem vas u zemlju kao što je vaša, u zemlju pšenice i mošta, u zemlju kruha i vinograda, u zemlju ulja i meda da biste živjeli i da ne pomrete. Ne dajte da vas Ezekija zaludi govoreći vam: Jahve će vas izbaviti.'"},{"v":33,"t":"Jesu li bogovi drugih naroda izbavili svoje zemlje iz ruku asirskoga kralja?"},{"v":34,"t":"Gdje su bogovi hamatski i arpadski, gdje su bogovi sefarvajimski, henski i ivski, gdje su bogovi samarijski da izbave Samariju iz ruke moje?"},{"v":35,"t":"Koji su među svim bogovima tih zemalja izbavili svoju zemlju iz moje ruke da bi Jahve izbavio Jeruzalem iz ruke moje?”"},{"v":36,"t":"Šutjeli su i ni riječi mu nisu odgovorili, jer kralj bijaše zapovjedio: “Ne odgovarajte mu!”"},{"v":37,"t":"Upravitelj dvora Elijakim, sin Hilkijin, pisar Šebna i savjetnik Joah, sin Asafov, dođoše k Ezekiji, razdrijevši haljine, i saopćiše mu riječi velikoga peharnika"}]},"19":{"hr":[{"v":1,"t":"Čuvši to, kralj Ezekija razdrije svoje haljine, obuče kostrijet i ode u Dom Jahvin."},{"v":2,"t":"Zatim posla Elijakima, upravitelja dvora, pisara Šebnu i svećeničke starješine, odjevene u kostrijet, k proroku Izaiji, sinu Amosovu."},{"v":3,"t":"Oni mu rekoše: “Ovako veli Ezekija: 'Ovo je dan nevolje, kazne i rugla. Prispješe djeca do rođenja, a nema snage da se rode."},{"v":4,"t":"Možda je Jahve, Bog tvoj, čuo što je rekao veliki peharnik koga je asirski kralj, gospodar njegov, poslao da se izruguje Bogu živome i možda će Jahve, Bog tvoj, kazniti riječi koje je čuo! Pomoli se pobožno za Ostatak koji je još preostao.'”"},{"v":5,"t":"Kad su sluge kralja Ezekije stigle k Izaiji,"},{"v":6,"t":"on im reče: “Kažite svome gospodaru: 'Ovako veli Jahve: Ne boj se riječi koje si čuo kada su na me hulile sluge kralja asirskoga."},{"v":7,"t":"Udahnut ću u njega duh i kad čuje jednu vijest, vratit će se u svoju zemlju. I učinit ću da u svojoj zemlji pogine od mača.'”"},{"v":8,"t":"Veliki peharnik vrati se i nađe asirskoga kralja gdje opsjeda Libnu, jer bijaše čuo da je kralj otišao iz Lakiša."},{"v":9,"t":"Dočuo je, naime, vijest o Tirhaku, kralju etiopskome: “Evo, izašao je da se bori protiv tebe.” Tada Sanherib ponovo uputi poslanike da kažu Ezekiji:"},{"v":10,"t":"“Ovako recite judejskom kralju Ezekiji: 'Neka te ne vara tvoj Bog, u koga se uzdaš, govoreći ti: Jeruzalem neće pasti u ruke asirskog kralja!"},{"v":11,"t":"Ti znaš što su asirski kraljevi učinili svim zemljama izručivši ih prokletstvu! A ti, ti li ćeš se spasiti?"},{"v":12,"t":"Jesu li bogovi spasili narode što su ih uništili moji oci: Gozance, Harane, Resefce i Edence, u Tel Basaru?"},{"v":13,"t":"Gdje je kralj hamatski, kralj arpadski, kralj Sefarvajima, Hene i Ive?'”"},{"v":14,"t":"Ezekija primi pismo iz ruke poslanikove i pročita ga. Zatim uđe u Dom Jahvin i razvi ga ondje pred Jahvom."},{"v":15,"t":"I pomoli se Ezekija Jahvi ovako: “Jahve, Bože Izraelov, koji stoluješ nad kerubima, ti si Bog jedini nad svim zemaljskim kraljevstvima, ti si stvorio nebo i zemlju."},{"v":16,"t":"Prikloni uho, Jahve, i počuj, otvori oči, Jahve, i vidi! Sanheribove čujder riječi koje poruči da izruga Boga živoga."},{"v":17,"t":"Istina je, o Jahve, asirski su kraljevi zatrli narode i zemlje njihove;"},{"v":18,"t":"pobacali im u oganj bogove; jer ne bijahu bogovi to, već djela ruku ljudskih, od drveta i kamena; zato ih i uništiše."},{"v":19,"t":"Ali sada, Jahve, Bože naš, izbavi nas iz ruke njegove da spoznaju sva kraljevstva zemlje da si ti, Jahve, Bog jedini.”"},{"v":20,"t":"Tada Izaija, sin Amosov, poruči Ezekiji: “Ovako veli Jahve, Bog Izraelov: 'Uslišah molitvu koju mi uputi zbog Sanheriba, kralja asirskog.'"},{"v":21,"t":"Evo riječi što je Jahve objavi protiv njega: Prezire te, ruga ti se djevica, kći sionska; za tobom maše glavom kći jeruzalemska."},{"v":22,"t":"Koga si grdio, hulio? Na koga si glasno vikao, ohol pogled dizao? Na Sveca Izraelova!"},{"v":23,"t":"Po slugama si svojim vrijeđao Gospoda. Govorio si: s mnoštvom kola ja popeh se na vrh gora, na najviše vrhunce Libanona. Posjekoh mu cedre najviše i čemprese ponajljepše. Dosegoh mu vrh najviši i vrt njegov šumoviti."},{"v":24,"t":"Kopao sam i pio sam vode tuđe; stopalima tad isuših sve rijeke egipatske."},{"v":25,"t":"Čuješ li dobro? Odavna to sam snovao, od iskona smišljao, sada to ostvarujem: na tebi je da prometneš gradove tvrde u razvaline."},{"v":26,"t":"Stanovnici njini, nemoćni, prepadnuti i smeteni, bjehu kao trava u polju, kao mlado zelenilo, kao trava vrh krovova opaljena vjetrom istočnim."},{"v":27,"t":"Znam kad se dižeš i kad sjedaš, kad izlaziš i kad se vraćaš."},{"v":28,"t":"Jer bjesnio si na me i jer obijest tvoja do ušiju mi dođe, prsten ću ti provuć' kroz nozdrve, uzde stavit' u žvale, vratit ću te putem kojim si i došao!"},{"v":29,"t":"A znak nek' ti bude ovo: Ove će se godine jesti što se samo okrÄunÄi, dogodine što samo uzraste, a treće godine sijte i žanjite, sadite vinograde, jedite im rod."},{"v":30,"t":"Preživjeli iz kuće Judine žilje će pustit' u dubinu, plodom rodit' u visinu."},{"v":31,"t":"Jer će iz Jeruzalema izići Ostatak, Sačuvani s gore Siona. Sve će to učinit' ljubomora Jahvina!"},{"v":32,"t":"Zato ovo govori Jahve o kralju asirskom: 'U ovaj grad on ući neće, ovamo strijele svoje neće izmetati, k njemu neće ni štit okrenuti, niti oko njega nasipe kopati."},{"v":33,"t":"Vratit će se putem kojim je i došao, u grad ovaj neće ući' - Jahvina je riječ."},{"v":34,"t":"Grad ću ovaj štitit, spasiti ga, sebe radi i rad sluge svoga Davida.”"},{"v":35,"t":"Te iste noći iziđe Anđeo Jahvin i pobi u asirskom taboru stotinu osamdeset i pet tisuća ljudi. Ujutro kad je valjalo ustati, gle, bijahu ondje sve sami mrtvaci."},{"v":36,"t":"Sanherib podiže tabor i ode. Vratio se u Ninivu."},{"v":37,"t":"Jednoga dana, dok se klanjao u hramu svoga boga Nisroka, njegovi ga sinovi Adramelek i Sareser ubiše mačem i pobjegoše u zemlju araratsku. Na njegovo se mjesto zakralji sin mu Asar-Hadon."}]},"20":{"hr":[{"v":1,"t":"U ono se vrijeme Ezekija razbolje nasmrt. Prorok Izaija, sin Amosov, dođe mu i reče: “Ovako veli Jahve: 'Uredi kuću svoju jer ćeš umrijeti; nećeš ozdraviti.'”"},{"v":2,"t":"Ezekija se okrenu zidu i ovako se pomoli Jahvi:"},{"v":3,"t":"“Ah, Jahve! Sjeti se milostivo da sam pred tobom hodio vjerno i poštena srca i da sam činio što je dobro u tvojim očima.” I Ezekija briznu u gorak plač."},{"v":4,"t":"Izaija još ne bijaše izišao iz središnjeg predvorja kad mu je stigla riječ Jahvina:"},{"v":5,"t":"“Vrati se i reci Ezekiji, glavaru moga naroda. Ovako veli Jahve, Bog tvoga oca Davida: 'Uslišao sam tvoju molitvu, vidio sam tvoje suze. Izliječit ću te; za tri dana uzići ćeš u Dom Jahvin."},{"v":6,"t":"Dodat ću tvome vijeku još petnaest godina. Izbavit ću tebe i ovaj grad iz ruku asirskoga kralja; zakrilit ću ovaj grad radi sebe i sluge svoga Davida.'”"},{"v":7,"t":"Izaija naloži: “Uzmite oblog od smokava, privijte mu ga na čir i on će ozdraviti.”"},{"v":8,"t":"Ezekija upita Izaiju: “Po kojem ću znaku prepoznati da će me Jahve izliječiti i da ću za tri dana uzići u Dom Jahvin?”"},{"v":9,"t":"Izaija odgovori: “Evo ti znaka od Jahve da će učiniti što je rekao: hoćeš li da se sjena pomakne za deset stupnjeva naprijed ili da se vrati za deset stupnjeva?”"},{"v":10,"t":"Ezekija odgovori: “Lako je sjeni pomaknuti se deset stupnjeva naprijed! Ne! Neka se sjena vrati natrag za deset stupnjeva!”"},{"v":11,"t":"Prorok Izaija zazva Jahvu i on učini da se sjena vrati za deset stupnjeva. Sišla je za deset posljednjih stupnjeva na Ahazovu sunčaniku."},{"v":12,"t":"U to vrijeme posla babilonski kralj Merodak-Baladan, sin Baladanov, pisma s darom Ezekiji, jer bijaše čuo da se razbolio i ozdravio."},{"v":13,"t":"Ezekija se obradova tome i pokaza poslanicima svoju riznicu - srebro, zlato, miomirise, mirisavo ulje - svoju oružanu i sve što je bilo u skladištima. Nije bilo ničega u njegovu dvoru i svemu njegovu gospodarstvu što im Ezekija nije pokazao."},{"v":14,"t":"Tada prorok Izaija dođe kralju Ezekiji i upita ga: “Što su rekli ti ljudi i odakle su došli k tebi?” Ezekija odgovori: “Došli su iz daleke zemlje, iz Babilona.”"},{"v":15,"t":"Izaija upita dalje: “Što su vidjeli u tvojem dvoru?” Ezekija odgovori: “Vidjeli su sve što je u mojem dvoru; nema u mojim skladištima ničega što im nisam pokazao.”"},{"v":16,"t":"Tada Izaija reče Ezekiji: “Čuj riječ Jahvinu:"},{"v":17,"t":"'Evo dolaze dani kada će sve što je u tvojem dvoru, sve što su tvoji oci nakupili do danas, biti odneseno u Babilon. Ništa neće ostati, ' kaže Jahve."},{"v":18,"t":"A od sinova što poteku od tebe, što ti se rode, neke će uzeti da budu uškopljeni dvorani u palači babilonskoga kralja.”"},{"v":19,"t":"Ezekija odgovori Izaiji: “Povoljna je riječ koju ti je Jahve objavio.” A mislio je: “Zašto ne? Ako bude mira i sigurnosti za moga života!”"},{"v":20,"t":"Ostala povijest Ezekijina, svi njegovi pothvati i kako je sagradio ribnjak i prorov da dovede vodu u grad, zar sve to nije zapisano u knjizi Ljetopisa judejskih kraljeva?"},{"v":21,"t":"Ezekija je počinuo sa svojim ocima, a njegov sin Manaše zakralji se mjesto njega."}]},"21":{"hr":[{"v":1,"t":"Manašeu je bilo dvanaest godina kad se zakraljio. Pedeset i pet godina kraljevao je u Jeruzalemu. Njegova se majka zvala Hefsi-Bah."},{"v":2,"t":"Činio je što je zlo u Jahvinim očima, povodeći se za gnusobama naroda što ih je Jahve protjerao pred Izraelovim sinovima."},{"v":3,"t":"Obnovio je uzvišice što ih bijaše oborio otac mu Ezekija, podigao je žrtvenik Baalu, načinio ašere kako bijaše učinio izraelski kralj Ahab; i stao se klanjati svoj vojsci nebeskoj i služiti joj."},{"v":4,"t":"Podigao je žrtvenike i u Domu Jahvinu, za koji bijaše rekao Jahve: “U Jeruzalemu će prebivati moje Ime zauvijek.”"},{"v":5,"t":"Sagradio je žrtvenike svoj nebeskoj vojsci u oba predvorja Doma Jahvina."},{"v":6,"t":"I sinove je svoje proveo kroz oganj. Vračao je, gatao, stvorio bajače i opsjenare, učinio je premnogo zla u očima Jahve i razjarivao ga."},{"v":7,"t":"Dao je načiniti lik Ašere i posadio ga u Domu, za koji Jahve bijaše rekao Davidu i njegovu sinu Salomonu: “U ovom Domu i u Jeruzalemu, koji sam izabrao među svim izraelskim plemenima, postavit ću svoje Ime zauvijek."},{"v":8,"t":"Neću više dati da noga Izraelaca uzmakne iz zemlje koju sam dao u baštinu njihovim očevima, samo ako budu držali i provodili u djelo sve što sam im zapovjedio: Zakon što im ga je objavio moj sluga Mojsije.”"},{"v":9,"t":"Ali oni nisu poslušali, Manaše ih je zaveo te su radili još gore nego narodi što ih je Jahve iskorijenio pred Izraelovim sinovima."},{"v":10,"t":"Tada je Jahve ovako govorio preko slugu svojih proroka:"},{"v":11,"t":"“Zato što je judejski kralj Manaše činio te gnusobe, zato što je učinio više zla nego što su prije njega radili Amorejci i što je zaveo Judejce svojim idolima,"},{"v":12,"t":"ovako veli Jahve, Bog Izraelov: 'Evo, učinit ću da dođe nevolja na Jeruzalem i Judeju, takva da će zazujati oba uha onima koji o njoj čuju."},{"v":13,"t":"Nategnut ću nad Jeruzalemom isto uže kao nad Samarijom, isto mjerilo kao nad kućom Ahabovom; zbrisat ću Jeruzalem kao što se briše zdjela pa se tad izvrne."},{"v":14,"t":"Odbacit ću ostatke svoje baštine, predat ću ih u ruke njihovih neprijatelja; služit će za plijen i grabež svim svojim neprijateljima"},{"v":15,"t":"jer su činili što je zlo u mojim očima jer su izazivali moj gnjev od dana kada su njihovi oci izišli iz Egipta pa sve do danas.'”"},{"v":16,"t":"I mnogo je nedužne krvi prolio Manaše, tako da se njome napunio Jeruzalem od jednoga kraja do drugoga, da se i ne spominje njegov grijeh kojim je zaveo Judu da čini što je zlo u očima Jahvinim."},{"v":17,"t":"Ostala povijest Manašeova, njegova djela i grijesi koje je počinio, zar sve to nije zapisano u knjizi Ljetopisa judejskih kraljeva?"},{"v":18,"t":"Manaše je počinuo kraj svojih otaca i sahranjen je u vrtu svojeg dvora, u vrtu Uzinu. Sin mu Amon zakralji se mjesto njega."},{"v":19,"t":"Amonu bijahu dvadeset i dvije godine kad je zavladao, a kraljevao je dvije godine u Jeruzalemu. Njegova se majka zvala Mešulemet, kći Harusova, i bila je iz Jotbe."},{"v":20,"t":"On je činio što je zlo u očima Jahvinim, kao što je činio njegov otac Manaše."},{"v":21,"t":"U svemu je slijedio put svoga oca, služio je idolima kojima je služio i njegov otac i klanjao im se."},{"v":22,"t":"On je ostavio Jahvu, Boga svojih praotaca, i nije hodio putem Jahvinim."},{"v":23,"t":"Amonovi se časnici urotiše protiv njega i ubiše kralja u dvoru."},{"v":24,"t":"Ali je prosti puk pobio sve one koji se bijahu urotili protiv kralja Amona i na njegovo mjesto zakraljio sina mu Jošiju."},{"v":25,"t":"Ostala povijest Amonova i sve što je činio, zar sve to nije zapisano u knjizi Ljetopisa judejskih kraljeva?"},{"v":26,"t":"Pokopali su ga u grobnicu njegova oca, u vrtu Uzinu, a njegov sin Jošija zakralji se mjesto njega."}]},"22":{"hr":[{"v":1,"t":"Jošiji je bilo osam godina kad se zakraljio. Kraljevao je trideset i jednu godinu u Jeruzalemu. Mati mu se zvala Jedida, kći Adajina, i bila je iz Boskata."},{"v":2,"t":"Činio je što je pravo u Jahvinim očima. U svemu je hodio putem svoga oca Davida, ne skrećući ni desno ni lijevo."},{"v":3,"t":"Osamnaeste godine svoga kraljevanja Jošija posla svoga tajnika Šafana, sina Asalijahina, sina Mešulamova, u Dom Jahvin i reče mu:"},{"v":4,"t":"“Idi velikom svećeniku Hilkiji da ti pripremi novac koji je odnesen u Dom Jahvin i koji su čuvari praga sakupili od naroda."},{"v":5,"t":"Neka ga uruči poslovođama postavljenim u Domu Jahvinu, a oni neka isplate radnike koji popravljaju Dom Jahvin,"},{"v":6,"t":"drvodjelje, graditelje i zidare, i da se kupuje drvo i kamenje klesano što je potrebno za popravak Doma."},{"v":7,"t":"Ali neka se ne traži od njih račun za uručeni novac jer oni rade pošteno.”"},{"v":8,"t":"Veliki svećenik Hilkija reče tajniku Šafanu: “Našao sam Knjigu Zakona u Domu Jahvinu.” I Hilkija dade knjigu Šafanu, koji ju je pročitao."},{"v":9,"t":"Tajnik Šafan dođe kralju te ga izvijesti: “Tvoje sluge”, reče on, “pokupile su novac koji se našao u Domu i predale su ga poslovođama postavljenim u Domu Jahvinu.”"},{"v":10,"t":"Tada tajnik Šafan obavijesti kralja: “Svećenik Hilkija dade mi jednu knjigu.” I Šafan je poče čitati pred kraljem."},{"v":11,"t":"Čuvši riječi Knjige Zakona, kralj razdrije haljine svoje."},{"v":12,"t":"I naredi svećeniku Hilkiji, Šafanovu sinu Ahikamu, Mikinu sinu Akboru, tajniku Šafanu i kraljevu sluzi Asaji:"},{"v":13,"t":"“Idite i upitajte Jahvu o meni, i o narodu, i o svoj Judeji zbog ove knjige što je nađena, jer je velika Jahvina jarost što se izlila na nas zato što naši očevi nisu slušali riječi ove knjige, nisu vršili što nam je u njoj napisano.”"},{"v":14,"t":"Svećenik Hilkija, Ahikam, Akbor, Šafan i Asaja odoše proročici Huldi, ženi Šaluma, sina Tikvina, sina Harkasova, čuvara odjeće; ona je živjela u Jeruzalemu, u novom gradu. Kad joj to kazaše,"},{"v":15,"t":"ona im reče: “Ovako veli Jahve, Bog Izraelov: 'Kažite čovjeku koji vas je poslao k meni:"},{"v":16,"t":"Ovako veli Jahve: Evo, dovest ću nesreću na ovaj grad i na njegove stanovnike, izvršit ću sve što kaže knjiga koju je pročitao judejski kralj."},{"v":17,"t":"Jer su me ostavili i prinose žrtve tuđim bogovima da bi me ljutili svim djelima ruku svojih, planut će jarost moja na to mjesto i neće se ugasiti.'"},{"v":18,"t":"A judejskom kralju, koji vas je poslao po Jahvin savjet, recite ovo: 'Ovako veli Jahve, Bog Izraelov: Riječi si čuo."},{"v":19,"t":"Ali kako ti je omekšalo srce i jer si se ponizio pred Jahvom čuvši što sam objavio tome gradu i njegovim stanovnicima, koje će pogoditi pustošenje i prokletstvo, i jer si razdro haljine svoje i plakao preda mnom, zato sam te uslišio' - riječ je Jahvina."},{"v":20,"t":"'Evo, sjedinit ću te s ocima tvojim i s mirom ćeš leći u grob da ne vidiš svojim očima svu nesreću koju ću svaliti na ovo mjesto.'” Oni odnesoše taj odgovor kralju."}]},"23":{"hr":[{"v":1,"t":"Tada kralj posla da se saberu kod njega sve judejske i jeruzalemske starješine."},{"v":2,"t":"Kralj potom uzađe u Dom Jahvin s Judejcima, Jeruzalemcima, svećenicima i prorocima i sa svim narodom, od najmanjega do najvećega. I pročita im sve riječi Knjige Saveza koja je nađena u Domu Jahvinu."},{"v":3,"t":"Kralj, stojeći na svome mjestu, obnovi pred Jahvom Savez da će slijediti Jahvu i držati se njegovih zapovijedi, pouka i uredaba svim srcem i svom dušom da bi ispunio sve stavke toga Saveza zapisane u ovoj knjizi. Sav je narod stupio u Savez."},{"v":4,"t":"Kralj je zapovjedio velikom svećeniku Hilkiji, svećenicima drugog reda i čuvarima hramskog praga da iz Svetišta Jahvina iznesu sve bogoslužne predmete što bijahu načinjeni za Baala, za Ašeru i za svu nebesku vojsku. Odredio je da sve to spale izvan Jeruzalema u poljima kidronskim, a pepeo je odnio u Betel."},{"v":5,"t":"Uklonio je lažne svećenike koje su judejski kraljevi postavili da pale kad na uzvišicama, u gradovima judejskim i u okolici Jeruzalema; i one koji su palili kad Baalu, suncu, mjesecu, zvijezdama i svoj vojsci nebeskoj."},{"v":6,"t":"Izvan Jeruzalema iznio je iz Doma Jahvina, u dolinu kidronsku, Ašeru i spalio ju je u dolini kidronskoj, satro u prah, a prah bacio na groblje sinova pučkih."},{"v":7,"t":"Razorio je stanove posvećenih bludnica koji su bili u Domu Jahvinu i u kojima su žene tkale haljine Ašeri."},{"v":8,"t":"Iz svih judejskih gradova doveo je svećenike i oskvrnuo je uzvišice gdje su ti svećenici prinosili kad, od Gebe do Beer Šebe. Zatim je srušio uzvišice pred vratima, one koje su bile na ulazu vrata Jošue, upravitelja grada, nalijevo kad se prilazi gradskim vratima."},{"v":9,"t":"Isto tako svećenici uzvišica nisu mogli uzlaziti žrtveniku Jahvinu u Jeruzalemu, ali su jeli kruhove bez kvasa među svojom braćom."},{"v":10,"t":"Oskvrnio je Tofet u dolini Ben Hinom, kako nitko ne bi svoga sina ili kćerku provodio kroz oganj u čast Moleku."},{"v":11,"t":"Razagnao je konje koje su judejski kraljevi prinijeli suncu na ulazu u Dom Jahvin, kraj sobe dvoranina Netan Meleka, koja se nalazila u blizini, i spalio je u ognju sunčana kola."},{"v":12,"t":"Žrtvenike na krovu koje bijahu sagradili judejski kraljevi i one koje je sagradio Manaše u oba predvorja Hrama Jahvina, kralj je srušio, uklonio ih odatle i bacio njihov prah u dolinu kidronsku."},{"v":13,"t":"Uzvišice koje su bile sučelice Jeruzalemu, na južnom dijelu Maslinske gore, i koje je izraelski kralj Salomon bio sagradio Aštarti, sramoti sidonskoj, Kemošu, sramoti moapskoj, i Milkomu, nakazi amonskoj - sve ih je kralj oskvrnio."},{"v":14,"t":"Razbio je stupove, iskorijenio ašere i njihova je mjesta ispunio ljudskim kostima."},{"v":15,"t":"Isto tako i žrtvenik u Betelu, uzvišicu koju je sagradio Jeroboam, sin Nebatov, koji je naveo Izraela na grijeh, kralj je srušio, oborio žrtvenik i tu uzvišicu, satro kamenje u prah, spalio ašere."},{"v":16,"t":"A kad se Jošija okrenuo i vidio grobove koji bijahu ondje na gori, posla da se sakupe kosti iz onih grobova i spali ih na žrtveniku. Tako ga je oskvrnuo, izvršavajući riječ Jahvinu, koju je objavio čovjek Božji (dok je Jeroboam bio na žrtveniku za vrijeme svečanosti). Okrenuvši se, Jošija baci oči na grob čovjeka Božjeg koji je objavio sve to"},{"v":17,"t":"i upita: “Kakav je ono spomenik što ga vidim?” Ljudi iz grada odgovoriše mu: “To je grob čovjeka Božjeg koji je došao iz Judeje i koji je prorekao sve ovo što si ti učinio s betelskim žrtvenikom.”"},{"v":18,"t":"“Pustite ga na miru”, reče kralj, “i neka nitko ne dira njegove kosti.” Tako su ostale njegove kosti netaknute s kostima proroka koji je došao iz Samarije."},{"v":19,"t":"Jošija je jednako razorio sve hramove uzvišica koje su izraelski kraljevi sagradili po gradovima Samarije da bi srdili Jahvu i učinio je s njima kao što je učinio u Betelu."},{"v":20,"t":"Sve svećenike uzvišica poklao je na žrtvenicima; na njima je spalio i ljudske kosti. Potom se vratio u Jeruzalem."},{"v":21,"t":"Kralj naredi svemu narodu: “Svetkujte Pashu u čast Jahve, Boga svoga, po običaju koji je zapisan u ovoj Knjizi Saveza.”"},{"v":22,"t":"Takva se Pasha nije svetkovala od vremena sudaca koji su sudili Izraelu i za sve vrijeme kraljeva izraelskih i judejskih."},{"v":23,"t":"Samo je osamnaeste godine kraljevanja Jošijina svetkovana takva Pasha u čast Jahve, u Jeruzalemu."},{"v":24,"t":"Osim toga, sve bajače i sve vračare, sve kućne bogove i idole i sve sramote koje se mogu vidjeti u zemlji judejskoj i Jeruzalemu - sve je to Jošija uklonio da izvrši riječi Zakona, zapisane u knjizi koju je našao Hilkija, svećenik Doma Jahvina."},{"v":25,"t":"Nije bilo prije njega takva kralja koji se obratio Jahvi svim srcem svojim, svom dušom svojom i svom snagom svojom, u svemu vjeran Zakonu Mojsijevu, a ni poslije njega nije mu bilo ravna."},{"v":26,"t":"Ipak Jahve nije odustao od plamena svoga velikoga gnjeva kojim je uskipio protiv Judejaca zbog svih izazova kojima ga je Manaše ljutio."},{"v":27,"t":"Jahve je odlučio: “Maknut ću Judejce ispred sebe kao što sam maknuo Izraela; odbacit ću ovaj grad koji sam izabrao, Jeruzalem, i Dom o kojem rekoh: 'Tu će biti Ime moje.'”"},{"v":28,"t":"Ostala povijest Jošijina i sve što je učinio, zar sve to nije zapisano u knjizi Ljetopisa judejskih kraljeva?"},{"v":29,"t":"U njegvo je vrijeme faraon Neko, egipatski kralj, krenuo protiv asirskoga kralja na rijeci Eufratu. Kralj Jošija pošao je preda nj, ali ga on ubi u Megidu, pri prvom susretu."},{"v":30,"t":"Sluge njegove prenesoše mu tijelo kolima iz Megida, odvezoše ga u Jeruzalem i sahraniše u njegovoj grobnici. Sav narod zemlje primi Joahaza, sina Jošijina; pomazaše ga i proglasiše kraljem namjesto njegova oca."},{"v":31,"t":"Joahazu bijahu dvadeset i tri godine kad se zakraljio. Kraljevao je tri mjeseca u Jeruzalemu. Njegova se majka zvala Hamitah, kći Jeremije, i bila je iz Libne."},{"v":32,"t":"On je činio što je zlo u očima Jahvinim, sve kao što su činili oci njegovi."},{"v":33,"t":"Faraon Neko bacio ga je u okove u Ribli, na području Hamata, da ne vlada u Jeruzalemu i udario je na zemlju danak od stotinu talenata srebra i deset talenata zlata."},{"v":34,"t":"Faraon Neko postavio je za kralja Elijakima, sina Jošijina, na mjesto njegova oca Jošije. I ime mu je promijenio u Jojakim. A Joahaza je uzeo i odveo u Egipat te on umrije ondje."},{"v":35,"t":"Jojakim je dao faraonu srebro i zlato, ali je nametnuo zemlji porez da bi smogao svotu koju je faraon zahtijevao. Svakome je nametnuo prema njegovu stanju, uzimao srebro i zlato koje je morao davati faraonu Neku."},{"v":36,"t":"Jojakimu je bilo dvadeset i pet godina kad je postao kraljem i kraljevao je jedanaest godina u Jeruzalemu. Materi mu je bilo ime Zebida, kći Pedajina, i bila je iz Rume."},{"v":37,"t":"On je činio što je zlo u očima Jahvinim, sve kao što su činili i oci njegovi."}]},"24":{"hr":[{"v":1,"t":"U njegovo je vrijeme došao Nabukodonozor, kralj babilonski, i Jojakim mu je bio podložan tri godine, zatim se ponovno pobunio protiv njega."},{"v":2,"t":"Ovaj pak posla protiv njega kaldejske pljačkaške čete, aramejske, moapske i amonske, sve ih posla protiv Judeje da je opustoše, potvrđujući riječ koju je Jahve bio objavio po slugama svojim prorocima."},{"v":3,"t":"To se dogodilo Judeji prema prijetnji Jahvinoj da će je istrijebiti ispred svoga lica zbog grijeha Manašeovih: zbog svega što je Manaše učinio"},{"v":4,"t":"i zbog nedužne krvi koju je prolio, natopio Jeruzalem krvlju nedužnom. Jahve nije htio oprostiti."},{"v":5,"t":"Ostala povijest Jojakimova i sve što je učinio, zar sve to nije zapisano u knjizi Ljetopisa judejskih kraljeva?"},{"v":6,"t":"Jojakim je počinuo kraj svojih otaca, a njegov sin Jojakin zavlada mjesto njega."},{"v":7,"t":"Egipatski kralj nije više izlazio iz zemlje, jer je babilonski kralj osvojio od Egipatskog potoka do rijeke Eufrata sve što je pripadalo egipatskom kralju."},{"v":8,"t":"Jojakinu je bilo osamnaest godina kad se zakraljio i kraljevao je tri mjeseca u Jeruzalemu. Materi mu je bilo ime Nehušta, kći Elnatana, i bila je iz Jeruzalema."},{"v":9,"t":"On je činio što je zlo u očima Jahvinim, sve kao što je činio i njegov otac."},{"v":10,"t":"U ono vrijeme krenu ljudstvo babilonskog kralja Nabukodonozora protiv Jeruzalema i grad je bio opkoljen."},{"v":11,"t":"Dođe i babilonski kralj Nabukodonozor da napadne grad, dok ga je njegovo ljudstvo opsjedalo."},{"v":12,"t":"Tada je judejski kralj Jojakin izišao pred babilonskoga kralja: on, njegova majka, njegove sluge, njegove vojskovođe i dvorani, a babilonski kralj zarobi ga - osme godine svoga kraljevanja."},{"v":13,"t":"On je odnio sve iz riznice Doma Jahvina i iz riznica kraljevskog dvora i razbio je sve zlatne predmete koje je Salomon, kralj Izraela, načinio za Svetište Jahvino. Tako se ispunila riječ Jahvina."},{"v":14,"t":"Odveo je u progonstvo sav Jeruzalem, sve vojskovođe i sve vrsne ratnike, oko deset tisuća prognanika, sa svim kovačima i bravarima. Jedino je preostao najsiromašniji narod zemlje."},{"v":15,"t":"Odveo je Jojakina u Babilon; tako isto i kraljevu majku i sve žene kraljeve, njegove dvorane, plemenitaše zemlje, sve ih je odveo iz Jeruzalema u progonstvo u Babilon."},{"v":16,"t":"Sve sposobne ljude, njih sedam tisuća na broju; kovače i bravare, tisuću na broju; sve ljude sposobne za boj, sve ih je kralj babilonski odveo u Babilon, u sužanjstvo."},{"v":17,"t":"Babilonski je kralj postavio za kralja mjesto Jojakina njegova strica Mataniju, ali mu je promijenio ime u Sidkija."},{"v":18,"t":"Sidkiji je bila dvadeset i jedna godina kad se zakraljio, a kraljevao je jedanaest godina u Jeruzalemu. Materi mu bijaše ime Hamitala, kći Jeremije, i bila je iz Libne."},{"v":19,"t":"Činio je što je zlo u očima Jahvinim, sve kao što je činio Jojakin."},{"v":20,"t":"To je zadesilo Jeruzalem i Judu zbog gnjeva Jahvina; Jahve ih napokon i odbaci ispred lica svoga. Sidkija se pobuni protiv babilonskog kralja."}]},"25":{"hr":[{"v":1,"t":"Devete godine njegova kraljevanja, desetoga dana desetoga mjeseca, krenu sam babilonski kralj Nabukodonozor sa svom svojom vojskom na Jeruzalem. Utabori se pred gradom i opasa ga opkopom."},{"v":2,"t":"Grad osta opkoljen do jedanaeste godine Sidkijina kraljevanja."},{"v":3,"t":"Devetoga dana četvrtoga mjeseca, kad je u gradu zavladala takva glad da priprosti puk nije imao ni kruha,"},{"v":4,"t":"neprijatelj provali u grad. Tada kralj i svi ratnici pobjegoše noću kroz vrata između dva zida nad Kraljevim vrtom - Kaldejci bijahu opkolili grad - i krenuše putem prema Arabi."},{"v":5,"t":"Kaldejske čete nagnuše u potjeru za kraljem i sustigoše ga na Jerihonskim poljanama, a sva se njegova vojska razbježala."},{"v":6,"t":"Kaldejci uhvatiše kralja i odvedoše ga u Riblu pred kralja babilonskog, koji mu izreče presudu."},{"v":7,"t":"Sidkijine sinove pokla pred njegovim očima, Sidkiji iskopa oči, okova ga verigama i odvede u Babilon."},{"v":8,"t":"Sedmoga dana petoga mjeseca - devetnaeste godine kraljevanja Nabukodonozora, kralja babilonskog - uđe u Jeruzalem Nebuzaradan, zapovjednik kraljeve tjelesne straže i časnik babilonskog kralja."},{"v":9,"t":"On zapali Dom Jahvin, kraljevski dvor i sve kuće u Jeruzalemu."},{"v":10,"t":"Kaldejske čete, pod zapovjednikom kraljevske tjelesne straže, razoriše zidine koje su okruživale Jeruzalem."},{"v":11,"t":"Nebuzaradan, zapovjednik kraljeve tjelesne straže, odvede u sužanjstvo ostatak naroda koji bijaše ostao u gradu, a tako i prebjege babilonskom kralju i ostalu svjetinu."},{"v":12,"t":"Neke od malih ljudi ostavi zapovjednik u zemlji kao vinogradare i ratare."},{"v":13,"t":"Kaldejci razbiše tučane stupove u Domu Jahvinu, podnožja i mjedeno more koji su bili u Domu Jahvinu i tuč odniješe u Babilon."},{"v":14,"t":"Uzeše i lonce, lopate, noževe, posudice i uopće sav tučani pribor koji se upotrebljavao za bogoslužja."},{"v":15,"t":"Zapovjednik uze i kadionice i škropionice, uopće sve što bijaše od zlata i srebra,"},{"v":16,"t":"dva stupa, jedno more i podnožja, što je Salomon dao izraditi za Dom Jahvin. Nije moguće procijeniti koliko je tuča bilo u svim tim predmetima."},{"v":17,"t":"Prvi stup bijaše visok osamnaest lakata, imao je glavicu od tuča, visoku pet lakata; obvijaše je oplet i mogranji, sve od tuča. Takav je bio i drugi stup."},{"v":18,"t":"Zapovjednik straže odveo je svećeničkog poglavara Seraju, drugog svećenika, Sefaniju, i tri čuvara praga."},{"v":19,"t":"Iz grada je odveo jednog dvoranina, vojničkog zapovjednika, pet ljudi iz kraljeve pratnje koji se zatekoše u gradu, pisara zapovjednika vojske koji je novačio puk i šezdeset pučana koji se također zatekoše u gradu."},{"v":20,"t":"Zapovjednik kraljevske tjelesne straže Nebuzaradan odvede ih pred kralja babilonskoga u Riblu."},{"v":21,"t":"I kralj babilonski zapovjedi da ih pogube u Ribli, u zemlji hamatskoj. Tako su judejski narod odveli s njegove rodne grude."},{"v":22,"t":"Narodu što je ostao u zemlji judejskoj i što ga je ostavio babilonski kralj Nabukodonozor - postavio je ovaj za upravitelja Gedaliju, sina Ahikamova, unuka Šafanova."},{"v":23,"t":"Svi vojni zapovjednici i njihovi ljudi saznaše da je babilonski kralj postavio zemlji za namjesnika Gedaliju i dođoše pred njega u Mispu: Netanijin sin Jišmael; Kareahov sin Johanan; sin Tanhumeta iz Netofe, Seraja; Maakatijev sin Jaazanija - oni i svi njihovi ljudi."},{"v":24,"t":"Gedalija se zakle njima i njihovim ljudima i reče: “Ne bojte se služiti Kaldejcima; ostanite u zemlji, budite podložni babilonskom kralju i bit će vam dobro.”"},{"v":25,"t":"Ali sedmoga mjeseca Jišmael, sin Netanijin, unuk Elišamin, koji bijaše kraljevskog roda, i još deset ljudi s njim ubiše Gedaliju te on umrije kao i svi Judejci i Kaldejci koji bijahu s njim u Mispi."},{"v":26,"t":"Tada sav narod, od maloga do velikog, i svi zapovjednici četa ustadoše i odoše u Egipat jer se bojahu Kaldejaca."},{"v":27,"t":"Trideset i sedme godine otkako je zasužnjen judejski kralj Jojakin, dvadeset i sedmog dana dvanaestoga mjeseca, babilonski kralj Evil Merodak u prvoj godini svoje vladavine pomilova judejskog kralja Jojakina i pusti ga iz tamnice."},{"v":28,"t":"Ljubezno je s njime razgovarao i stolicu mu postavio više nego ostalim kraljevima koji bijahu s njim u Babilonu."},{"v":29,"t":"Jojakin je odložio svoje tamničke haljine i jeo s kraljem za istim stolom svega svoga vijeka."},{"v":30,"t":"Do kraja njegova života babilonski mu je kralj trajno, iz dana u dan, davao uzdržavanje."}]}},"1CH":{"1":{"hr":[{"v":1,"t":"Adam, Šet, Enoš,"},{"v":2,"t":"Kenan, Mahalalel, Jared,"},{"v":3,"t":"Henok, Metušalah, Lamek,"},{"v":4,"t":"Noa, Šem, Ham i Jafet."},{"v":5,"t":"Sinovi Jafetovi: Gomer, Magog, Madaj, Javan, Tubal, Mešek i Tiras."},{"v":6,"t":"Gomerovi sinovi: Aškenaz, Rifat i Togarma."},{"v":7,"t":"Javanovi sinovi: Eliša, Taršiš, Kitijci i Dodanci."},{"v":8,"t":"Hamovi sinovi: Kuš, Misrajim, Put i Kanaan."},{"v":9,"t":"Kuševi sinovi: Seba, Havila, Sabta, Rama i Sabteka; Ramini sinovi: Šeba i Dedan."},{"v":10,"t":"Kušu se rodi Nimrod, koji bijaše prvi vlastodržac na zemlji."},{"v":11,"t":"Od Misrajima potekli su Ludijci, Anamijci, Lehabijci, Neftuhijci,"},{"v":12,"t":"Patrušani i Kasluhijci, od kojih su potekli Filistejci i Kaftorci."},{"v":13,"t":"Kanaan rodi Sidona, svog prvenca, i Heta,"},{"v":14,"t":"i Jebusejce, Amorejce, Girgašane,"},{"v":15,"t":"Hivijce, Arkijce, Sinijce,"},{"v":16,"t":"Arvadijce, Semarijce i Hamatijce."},{"v":17,"t":"Šemovi sinovi: Elam, Ašur, Arpakšad, Lud i Aram. Aramovi sinovi: Us, Hul, Geter i Mešek."},{"v":18,"t":"Arpakšadu se rodi Šelah, Šelahu se rodi Eber."},{"v":19,"t":"Eberu se rodiše dva sina: jednom bješe ime Peleg, jer se za njegova doba razdijelila zemlja. Njegovu je bratu bilo ime Joktan."},{"v":20,"t":"Od Joktana se rodiše Almodad, Šelef, Hasarmavet, Jerah,"},{"v":21,"t":"Hadoram, Uzal, Dikla,"},{"v":22,"t":"Obal, Abimael, Šeba,"},{"v":23,"t":"Ofir, Havila i Jobab. Svi su to sinovi Joktanovi."},{"v":24,"t":"Šem, Arpakšad, Šalah,"},{"v":25,"t":"Eber, Peleg, Rau,"},{"v":26,"t":"Serug, Nahor, Tarah,"},{"v":27,"t":"Abram, to jest Abraham."},{"v":28,"t":"Abrahamovi sinovi: Izak i Jišmael."},{"v":29,"t":"Ovo je njihovo rodoslovlje: Jišmaelov prvenac Nebajot, zatim Kedar, Adbeel, Mibsam,"},{"v":30,"t":"Mišma, Duma, Masa, Hadad, Tema,"},{"v":31,"t":"Jetur, Nafiš i Kedma. To su Jišmaelovi sinovi."},{"v":32,"t":"Sinovi Keture, Abrahamove inoče: ona rodi Zimrana, Jokšana, Medana, Midjana, Jišbaka i Šuaha. Sinovi Jokšanovi jesu: Šeba i Dedan."},{"v":33,"t":"Midjanovi su sinovi bili: Efa, Efer, Henok, Abida i Eldaa. Svi su oni bili Keturini sinovi."},{"v":34,"t":"Abrahamu se rodi Izak; Izakovi su sinovi bili: Ezav i Izrael."},{"v":35,"t":"Ezavovi su sinovi bili: Elifaz, Reuel, Jeuš, Jalam i Korah."},{"v":36,"t":"Elifazovi su sinovi bili: Teman, Omar, Sefi, Gatan, Kenaz, Timna i Amalek."},{"v":37,"t":"Reuelovi su sinovi bili: Nahat, Zerah, Šama i Miza."},{"v":38,"t":"Seirovi su sinovi bili: Lotan, Šobal, Sibeon, Ana, Dišon, Eser i Dišan."},{"v":39,"t":"Lotanovi su sinovi bili: Hori i Homam; Lotanova je sestra bila Timna."},{"v":40,"t":"Šobalovi su sinovi bili: Alvan, Manahat, Ebal, Šefi i Onam. Sibeonovi su sinovi bili: Aja i Ana."},{"v":41,"t":"Anin je sin bio Dišon, a Dišonovi su sinovi bili: Hamram, Ešban, Jitran i Keran."},{"v":42,"t":"Eserovi su sinovi bili: Bilhan, Zaavan i Jaakan. Dišonovi su sinovi bili Us i Aran."},{"v":43,"t":"Evo kraljeva koji su kraljevali u zemlji edomskoj prije nego je zavladao kralj sinova Izraelovih: Bela, sin Beorov; gradu mu je bilo ime Dinhaba."},{"v":44,"t":"Kad je umro Bela, na njegovo se mjesto zakraljio Jobab, sin Zareha iz Bosre."},{"v":45,"t":"Kad je umro Jobab, zakraljio se na njegovo mjesto Hušam iz temanske zemlje."},{"v":46,"t":"Kad je umro Hušam, zakraljio se na njegovo mjesto Bedadov sin Hadad, koji je potukao Midjance na Moapskom polju; gradu mu je bilo ime Avit."},{"v":47,"t":"Kad je umro Hadad, zakraljio se na njegovo mjesto Samla iz Masreke."},{"v":48,"t":"Kad je umro Samla, zakraljio se na njegovo mjesto Šaul iz Rehobota na Rijeci."},{"v":49,"t":"Kad umrije Šaul, zavlada Baal Hanan, Akborov sin."},{"v":50,"t":"Kad je umro Baal Hanan, zavladao je Hadad; gradu mu je bilo ime Pai. Žena mu se zvala Mehetabela. Bila je kći Matredova iz Me Zahaba."},{"v":51,"t":"Kad je umro Hadad, nastali su knezovi u Edomu: knez Timna, knez Alva, knez Jetet,"},{"v":52,"t":"knez Oholibama, knez Ela, knez Pinon,"},{"v":53,"t":"knez Kenaz, knez Teman, knez Mibsar,"},{"v":54,"t":"knez Magdiel i knez Iram. To su bili knezovi edomski."}]},"2":{"hr":[{"v":1,"t":"Evo Izraelovih sinova: Ruben, Šimun, Levi, Juda, Jisakar i Zebulun,"},{"v":2,"t":"Dan, Josip i Benjamin, Naftali, Gad i Ašer."},{"v":3,"t":"Judini sinovi: Er, Onan i Šela. Ta mu je tri rodila Kanaanka, Šuina kći. Ali Er, Judin prvenac, bijaše nevaljao u Jahvinim očima i Jahve ga pogubi."},{"v":4,"t":"Njegova nevjesta Tamara rodi mu Peresa i Zeraha. U svemu je bilo pet Judinih sinova."},{"v":5,"t":"Peresovi su sinovi bili: Hesron i Hamul."},{"v":6,"t":"Zerahovi su sinovi bili: Zimri, Etan, Heman, Kalkol i Dara; u svemu pet."},{"v":7,"t":"Karmijevi su sinovi bili: Akar, koji je nanio zlo Izraelu prekršivši kletvu."},{"v":8,"t":"A sinovi Etanovi: Azarja."},{"v":9,"t":"Hesronovi sinovi koji mu se rodiše bijahu: Jerahmeel, Ram i Kelubaj."},{"v":10,"t":"Ram rodi Aminadaba, a Aminadab rodi Nahšona, kneza Judinih sinova."},{"v":11,"t":"Nahšon rodi Salmu, Salma rodi Boaza."},{"v":12,"t":"Boaz rodi Obeda, Obed rodi Jišaja."},{"v":13,"t":"Jišaj rodi prvenca Eliaba, drugog Abinadaba, trećeg Šimu,"},{"v":14,"t":"četvrtog Netanela, petog Radaja,"},{"v":15,"t":"šestog Osema, sedmoga Davida."},{"v":16,"t":"Sestre im: Sarviju i Abigajilu. Sarvijini su sinovi bili: Abišaj, Joab, Asahel, trojica."},{"v":17,"t":"Abigajila je rodila Amasu, Amasin je otac bio Jišmaelac Jeter."},{"v":18,"t":"Hesronov sin Kaleb imao je sa ženom Azubom i s Jeriotom sinove, a sinovi su mu bili: Ješer, Šobab i Ardon."},{"v":19,"t":"Kad je umrla Azuba, uze Kaleb za ženu Efratu i ona mu rodi Hura."},{"v":20,"t":"Hur rodi Urija, a Uri rodi Besalelu."},{"v":21,"t":"Potom Hesron uze kćer Makira, oca Gileadova; uzeo ju je za ženu kad mu je bilo šezdeset godina i ona mu rodi Seguba."},{"v":22,"t":"Segub rodi Jaira, koji je imao dvadeset i tri grada u gileadskoj zemlji."},{"v":23,"t":"Ali su Gešurci i Aramejci osvojili od njih Jairova Sela, Kenat sa selima, šezdeset gradova. To su sve osvojili sinovi Makira, oca Gileadova."},{"v":24,"t":"Kad je umro Hesron u Kaleb Efrati, Hesronova žena Abija rodi mu Ašhura, oca Tekoina."},{"v":25,"t":"Sinovi Jerahmeela, Hesronova prvenca, bili su: prvenac Ram, pa Buna, Oren, Osem i Ahija."},{"v":26,"t":"Jerahmeel je imao i drugu ženu, zvala se Atara, koja je bila Onamova majka."},{"v":27,"t":"Sinovi Rama, Jerahmeelova prvenca, bili su Maas, Jamin i Eker."},{"v":28,"t":"Onamovi su sinovi bili: Šamaj i Jada; Šamajevi sinovi: Nadab i Abišur."},{"v":29,"t":"Abišurova se žena zvala Abihajla, koja mu rodi Ahbana i Molida."},{"v":30,"t":"Nadabovi su sinovi bili: Seled i Afajim, ali je Seled umro bez djece."},{"v":31,"t":"Sinovi su Afajimovi bili: Jiši; Jišijevi sinovi: Šešan; Šešanov sin Ahlaj."},{"v":32,"t":"Sinovi Jade, brata Šamajeva, bili su: Jeter i Jonatan; ali je Jeter umro bez djece."},{"v":33,"t":"Jonatanovi su sinovi bili: Pelet i Zaza. To su bili Jerahmeelovi sinovi."},{"v":34,"t":"Šešan nije imao sinova, nego kćeri; ali je Šešan imao slugu Egipćanina po imenu Jarhu."},{"v":35,"t":"Zato je Šešan dao kćer sluzi Jarhi za ženu i ona mu rodi Ataja."},{"v":36,"t":"Ataj rodi Natana, Natan rodi Zabada."},{"v":37,"t":"Zabad rodi Eflala, Eflal rodi Obeda;"},{"v":38,"t":"Obed rodi Jehua, Jehu rodi Azarju,"},{"v":39,"t":"Azarja rodi Helesa, Heles rodi Elasu;"},{"v":40,"t":"Elasa rodi Sismaja, Sismaj rodi Šaluma,"},{"v":41,"t":"Šalum rodi Jekamju, Jekamja rodi Elišamu."},{"v":42,"t":"Sinovi Kaleba, Jerahmeelova brata, bili su: njegov prvenac Meša, otac Zifov; sinovi oca Mareše bili su: Hebron."},{"v":43,"t":"Hebronovi sinovi Korah, Tapuah, Rekem i Šema."},{"v":44,"t":"Šema rodi Rahama, oca Jorkoamova, a Rekem rodi Šamaja."},{"v":45,"t":"Šamajev je sin bio Maon, a Maon je bio otac Bet-Sarov."},{"v":46,"t":"Efa, Kalebova inoča, rodila je Harana, Mosu i Gazeza; Haran je rodio Gazeza."},{"v":47,"t":"Johdajevi su sinovi bili: Regem, Jotam, Gešan, Felet, Efa i Šaaf."},{"v":48,"t":"Maaka, Kalebova inoča, rodila je Šebera i Tirhanu."},{"v":49,"t":"Rodila je Šaafa, oca Madmanina, Ševu, oca Makbenina, i oca Gibina; a Kalebova je kći bila Aksa."},{"v":50,"t":"To su bili sinovi Kalebovi. A sinovi Hura, Efratina prvenca: Šobal, otac Kirjat Jearimov,"},{"v":51,"t":"Salma, otac Betlehemov, i Haref, otac Bet-Gaderov."},{"v":52,"t":"A sinovi Šobala, oca Kirjat Jearimova: Reaja, polovica Manahaćana."},{"v":53,"t":"Kirjatjearimske su porodice bile: Jitrani, Pućani, Šumaćani i Mišrani; od njih su potekli Soraćani i Eštaoljani."},{"v":54,"t":"Salmini su sinovi: Betlehem, Netofaćani, Atrot, Bet Joab i polovina Manahaćana, Saraćani."},{"v":55,"t":"Književničke obitelji koje su živjele u Jabesu bile su: Tiraćani, Simeaćani, Sukaćani. To su Kinejci koji su potekli od Hamata, oca Rekabova doma."}]},"3":{"hr":[{"v":1,"t":"Ovo su Davidovi sinovi koji mu se rodiše u Hebronu: prvenac Amnon od Jizreelke Ahinoame, drugi Daniel od Karmelke Abigajle,"},{"v":2,"t":"treći Abšalom, sin Maake, kćeri Talmaja, gešurskoga kralja, četvrti Adonija, sin Hagitin,"},{"v":3,"t":"peti Šefatja od Abitale, šesti Jitream od njegove žene Egle."},{"v":4,"t":"Šest mu se sinova rodilo u Hebronu, gdje je kraljevao sedam godina i šest mjeseci; a trideset je i tri godine kraljevao u Jeruzalemu."},{"v":5,"t":"Ovi mu se sinovi rodiše u Jeruzalemu: Šimeja, Šobab, Natan i Salomon; četiri od Bat-Šebe, kćeri Amielove."},{"v":6,"t":"Jibhar, Elišama, Elifalet,"},{"v":7,"t":"Nogah, Nefeg, Jafija,"},{"v":8,"t":"Elišama, Elijada, Elifelet: devet."},{"v":9,"t":"Sve Davidovi sinovi osim inočkih sinova i njihove sestre Tamare."},{"v":10,"t":"Salomonov je sin bio Roboam, njegov sin Abija, njegov sin Asa, njegov sin Jošafat,"},{"v":11,"t":"njegov sin Joram, njegov sin Ahazja, njegov sin Joaš,"},{"v":12,"t":"njegov sin Amasja, njegov sin Azarja, njegov sin Jotam,"},{"v":13,"t":"njegov sin Ahaz, njegov sin Ezekija, njegov sin Manaše,"},{"v":14,"t":"njegov sin Amon, njegov sin Jošija."},{"v":15,"t":"Jošijini su sinovi bili: prvenac Johanan, drugi Jojakim, treći Sidkija, četvrti Šalum."},{"v":16,"t":"Jojakimovi su sinovi bili: Jekonija, njegov sin, i Sidkija, njegov sin."},{"v":17,"t":"Sinovi sužnja Jekonje bili su Šealtiel, njegov sin,"},{"v":18,"t":"Malkiram, Pedaja, Šenasar, Jekamja, Jošama i Nebadja."},{"v":19,"t":"Pedajini su sinovi bili: Zerubabel i Šimej; Zerubabelovi sinovi: Mešulam i Hananija, i sestra im Šelomita."},{"v":20,"t":"Hašuba, Ohel, Berekja, Hasadja i Jušab-Hesed, njih petorica."},{"v":21,"t":"Hananijini su sinovi bili: Pelatja i Jišaja, Refajini sinovi, Arnanov sin, Obadjin sin, Šekanijin sin."},{"v":22,"t":"Šekanijini su sinovi bili: Šemaja, a Šemajini su sinovi bili: Hatuš, Jigal, Barijah, Nearja i Šafat, šestorica."},{"v":23,"t":"Nearjini su sinovi bili Elijoenaj, Ezekija i Azrikam, trojica."},{"v":24,"t":"Elijoenajevi su sinovi bili Hodavja, Elijašib, Felaja, Akub, Johanan, Delaja i Anani, sedmorica."}]},"4":{"hr":[{"v":1,"t":"Judini su sinovi bili: Peres, Hesron, Karmi, Hur i Šobal."},{"v":2,"t":"Šobalov sin Reaja rodi Jahata, a Jahat rodi Ahumaja i Lahada. To su soratski rodovi."},{"v":3,"t":"Ovo su sinovi od oca Etama: Jizreel, Jišma i Jidbaš, a njihovoj je sestri bilo ime Haslelponija."},{"v":4,"t":"Fenuel je bio otac Gedoru, a Ezer je bio Hušin otac. To su bili sinovi Hura, prvenca Efrate, oca Betlehema."},{"v":5,"t":"A otac Tekoe Ašhur imao je dvije žene, Helu i Naaru."},{"v":6,"t":"Naara mu je rodila Ahuzama, Hefera, Temnance i Ahaštarce. To su Naarini sinovi."},{"v":7,"t":"Helini su sinovi bili: Seret, Sohar i Etnan."},{"v":8,"t":"Kos rodi Anuba i Hasobebu i porodice Harumova sina Aharhela."},{"v":9,"t":"Jabes je bio izvrsniji među braćom i mati mu je nadjela ime Jabes govoreći: “Rodila sam ga s bolom.”"},{"v":10,"t":"Jabes je prizvao Izraelova Boga govoreći: “Ako me odista blagoslivljaš, raširi moje područje, neka bude tvoja ruka uza me i sačuvaj me oda zla, tako da se ne mučim!” Ispuni mu Bog za što ga je molio."},{"v":11,"t":"Šuhin brat Kelub rodi Mehira; on je bio Eštonov otac."},{"v":12,"t":"Od Eštona poteče Bet Rafa, Paseah i Tehina, otac Ir Nahaša. To su Rekini ljudi."},{"v":13,"t":"A Kenazovi su sinovi bili: Otniel i Seraja. Otnielovi sinovi: Hatat i Meonotaj."},{"v":14,"t":"Meonotaj rodi Ofru; Šeraja rodi Joaba, oca onih što žive u Dolini rukotvoraca, jer bijahu rukotvorci."},{"v":15,"t":"Sinovi Jefuneova sina Kaleba bili su: Ir, Ela i Naam; Elin je sin bio Kenaz."},{"v":16,"t":"Jehalelelovi su sinovi bili Zif, Zifa, Tirja i Asrael."},{"v":17,"t":"Ezrini sinovi: Jeter, Mered, Efer i Jalon; Jeter rodi Mirjamu, Šamaja i Jišboha, Eštemoina oca."},{"v":18,"t":"Njegova žena Judejka rodila je Jereda, Gedorova oca, Hebera, Sokova oca, i Jekutiela, Zanoahova oca. To su bili sinovi Bitje, faraonove kćeri koju je za ženu uzeo Mered."},{"v":19,"t":"Sinovi Hodijine žene, sestre Nahama, Keilina oca, bili su: Šimun, otac Jomama Garmijca, i Eštemoa Maakaćanin."},{"v":20,"t":"Šimunovi su sinovi bili: Amnon, Rina, Ben-Hanan i Tilon. Išijevi sinovi: Zohet i Ben-Zohet."},{"v":21,"t":"Sinovi Judina sina Šele bili su: Er, Lekin otac, Lada, Marešin otac, i obitelji platnarske kuće u Bet Ašbeji;"},{"v":22,"t":"Jokim i ljudi iz Kozebe Joaš i Saraf, koji su vladali nad Moabom i vratili se u Betlehem. Ali su to stari događaji."},{"v":23,"t":"To su bili lončari koji su živjeli u Netajimu i u Gederi kod kralja i bili su ondje zaposleni u njega."},{"v":24,"t":"Šimunovi su sinovi bili Nemuel, Jamin, Jarib, Zerah i Šaul."},{"v":25,"t":"Njegov je sin bio Šalum, a njegov je sin Mibsam, njegov sin Mišma."},{"v":26,"t":"Mišmini su sinovi bili: Hamuel, sin mu, i njegov sin Zakur i njegov sin Šimej."},{"v":27,"t":"Šimej je imao šesnaest sinova i šest kćeri; njegova braća nisu imala mnogo sinova, i sve njihove porodice nije bilo tako mnogo kao Judinih sinova."},{"v":28,"t":"Živjeli su u Beer Šebi, Moladi i Hasar Šualu,"},{"v":29,"t":"u Bilhi, u Esemu, u Toladu,"},{"v":30,"t":"u Betuelu, u Hormi, u Siklagu,"},{"v":31,"t":"u Bet Markabotu, u Hasar Susimu, u Bet Biriju i u Šaarajimu. To su bili njihovi gradovi do Davidova kraljevanja."},{"v":32,"t":"A njihova su naselja bila: Etam i Ajin, Rimon, Token i Ašan, pet gradova."},{"v":33,"t":"I sva njihova naselja što su bila oko tih gradova do Baala. To su bili njihovi stanovi i njihovi plemenski popisi."},{"v":34,"t":"Mešobad, Jamlek i Amasjin sin Joša,"},{"v":35,"t":"Joel i Jehu, sin Jošibje, sina Serajina, sina Asielova,"},{"v":36,"t":"Elijoenaj, Jaakoba, Ješohaja, Asaja, Adiel, Jesimiel i Benaja,"},{"v":37,"t":"Ziza, sin Šifija, sina Alonova, sina Jedajeva, sina Šimrijeva, sina Šemajina."},{"v":38,"t":"Ti su imenovani bili starješine svojim rodovima i njihove su se porodice veoma umnožile."},{"v":39,"t":"Zato su otišli do mjesta kako se ide u Gedor do istočne strane doline da traže pašu stoci."},{"v":40,"t":"Našli su obilatu i dobru pašu i prostranu, sigurnu i mirnu zemlju. Budući da su ondje prije živjeli Hamovi potomci,"},{"v":41,"t":"Šimunovci, poimence popisani, navališe za vremena judejskoga kralja Ezekije te razbiše njihove šatore i njihove zaklone koji se nađoše ondje. Baciše na njih kletvu, koja traje do današnjega dana, i nastaniše se na njihovo mjesto jer su ondje bili pašnjaci za njihovu stoku."},{"v":42,"t":"Onda su neki među onima što su pripadali Šimunovim sinovima, njih pet stotina, izbili na planinu Seir, na čelu s Felatjom, Nearjom, Refajom i Uzielom, Išijevim sinovima."},{"v":43,"t":"Oni pobiše ostatak koji se spasio između Amalečana i naseliše se ondje do današnjega dana."}]},"5":{"hr":[{"v":1,"t":"Sinovi Izraelova prvenca Rubena. On je doista bio prvenac; ali kad je oskvrnuo očevu postelju, njegovo je pravo prvorodstva bilo dano sinovima Izraelova sina Josipa, ali im nije bilo upisano u rodovnik,"},{"v":2,"t":"jer je Juda nadvladao među braćom, a od njega se rodio knez. Ipak je pravo prvorodstva pripalo Josipu."},{"v":3,"t":"Sinovi Izraelova prvenca Rubena bili su Henok, Falu, Hesron i Karmi."},{"v":4,"t":"Joelovi sinovi: njegov sin Šemaja, njegov sin Gog, njegov sin Šimej,"},{"v":5,"t":"njegov sin Mika, njegov sin Reaja, njegov sin Baal,"},{"v":6,"t":"njegov sin Beera, koga je odveo u sužanjstvo asirski kralj Tiglat Pileser; on je bio poglavar Rubenova plemena."},{"v":7,"t":"Njegovoj braći, po obiteljima, kad su se zapisali u plemenski rodovnik po naraštajima, bio je poglavar Jeiel, Zaharija,"},{"v":8,"t":"Bela, sin Azazov, sin Šemin, sin Joelov. On je živio u Aroeru i do Neba i Baal Meona."},{"v":9,"t":"Prema istoku njegova se zemlja prostirala do ulaza u pustinju, od rijeke Eufrata, jer mu se stoka umnožila u gileadskoj zemlji."},{"v":10,"t":"Za Šaulovih vremena vojevali su s Hagrijcima koji su izginuli od njihove ruke; tako su se naselili u njihove šatore po svemu istočnom području od Gileada."},{"v":11,"t":"Gadovi su sinovi živjeli blizu njih u bašanskoj zemlji do Salke."},{"v":12,"t":"Poglavar je bio Joel, a drugi Šafan, pa Janaj i Šafat u Bašanu."},{"v":13,"t":"Njihova su braća po svojim rodovima bila: Mihael, Mešulam, Šeba, Joraj, Jakan, Zija, Eber, sedmorica."},{"v":14,"t":"To su bili sinovi Abihajila, sina Hurija, sina Jaroaha, sina Gileada, sina Mihaela, sina Ješišaja, sina Jahdona, sina Buza."},{"v":15,"t":"Ahi, sin Abdiela, Gunijeva sina, bio je poglavar njihova roda."},{"v":16,"t":"Živjeli su u Gileadu i u njihovim zaseocima te po svim šaronskim pašnjacima do njihovih krajeva."},{"v":17,"t":"Svi su bili zapisani u plemenski rodovnik za vremena judejskoga kralja Jotama i za vremena izraelskoga kralja Jeroboama."},{"v":18,"t":"Rubenovih i Gadovih sinova, i polovine Manašeova plemena, hrabrih junaka koji su nosili štit i mač te zapinjali luk i bili vješti boju, bijaše četrdeset tisuća sedam stotina i šezdeset vojnika."},{"v":19,"t":"Ratovali su protiv Hagrijaca, Iturejaca, Nafišejaca i Nodabejaca."},{"v":20,"t":"U boju su zavapili k Bogu i on ih je uslišao jer su se pouzdali u nj: potpomognuti su protiv neprijatelja te su im predani u ruke Hagrijci sa svim njihovim saveznicima."},{"v":21,"t":"Zaplijenili su njihovu stoku - pedeset tisuća deva, dvije stotine i pedeset tisuća ovaca i koza i dvije tisuće magaraca - i odveli u ropstvo sto tisuća ljudi."},{"v":22,"t":"Pobijenih je mnogo palo, jer je taj boj bio od Boga; onda se naseliše na njihovo mjesto do sužanjstva."},{"v":23,"t":"Sinovi polovine Manašeova plemena nastanili su se u toj zemlji od Bašana do Baal Hermona i Šenira i do Hermonske gore. I bijahu se umnožili."},{"v":24,"t":"Ovo su bili poglavari njihovih rodova: Efer, Jiši, Eliel, Azriel, Jeremija, Hodavja i Jahdiel, hrabri junaci i ugledni muževi: poglavari u svojim rodovima."},{"v":25,"t":"Ali kad su se iznevjerili Bogu svojih otaca i odali se preljubu s bogovima naroda one zemlje koje je Bog iskorijenio pred njima,"},{"v":26,"t":"probudio je Izraelov Bog neprijateljstvo asirskoga kralja Pula i neprijateljstvo asirskoga kralja Tiglat Pilesera. Oni su odveli u sužanjstvo Rubenovo i Gadovo pleme i polovinu Manašeova plemena. Doveli su ih u Helah, Habor i Haru i na Gozansku rijeku do današnjega dana."},{"v":27,"t":"Levijevi su sinovi bili Geršom, Kehat i Merari."},{"v":28,"t":"Kehatovi sinovi: Amram, Jishar, Hebron i Uziel."},{"v":29,"t":"Amramovi sinovi: Aron, Mojsije i Mirjama. Aronovi sinovi: Nabad i Abihu, Eleazar i Itamar."},{"v":30,"t":"Eleazar rodi Pinhasa, Pinhas rodi Abišuu;"},{"v":31,"t":"Abišua rodi Bukija, Buki rodi Uziju;"},{"v":32,"t":"Uzija rodi Zerahju; Zerahja rodi Merajota."},{"v":33,"t":"Merajot rodi Amarju; Amarja rodi Ahituba;"},{"v":34,"t":"Ahitub rodi Sadoka; Sadok rodi Ahimaasa;"},{"v":35,"t":"Ahimaas rodi Azarju, Azarja rodi Johanana;"},{"v":36,"t":"Johanan rodi Azarju, koji je bio svećenik u Hramu što ga je sagradio Salomon u Jeruzalemu."},{"v":37,"t":"Azarja rodi Amarju; Amarja rodi Ahituba;"},{"v":38,"t":"Ahitub rodi Sadoka, Sadok rodi Šaluma;"},{"v":39,"t":"Šalum rodi Hilkiju, Hilkija rodi Azarju;"},{"v":40,"t":"Azarja rodi Seraju; Seraja rodi Josadaka."},{"v":41,"t":"Josadak je otišao kad je Jahve odveo u sužanjstvo Judu i Jeruzalem Nabukodonozorovom rukom."}]},"6":{"hr":[{"v":1,"t":"Levijevi su sinovi bili Geršom, Kehat i Merari."},{"v":2,"t":"Evo imena Geršomovih sinova: Libni i Šimej."},{"v":3,"t":"Kehatovi su sinovi bili: Amram, Jishar, Hebron i Uziel."},{"v":4,"t":"Merarijevi sinovi: Mahli i Muši. Ovo su rodovi Levijevaca po svojim ocima."},{"v":5,"t":"Od Geršoma: sin mu Libni, njegov sin Jahat, njegov sin Zima,"},{"v":6,"t":"njegov sin Joah, njegov sin Ido, njegov sin Zerah, njegov sin Jeatraj."},{"v":7,"t":"Kehatovi sinovi: sin mu Aminadab, njegov sin Korah, njegov sin Asir,"},{"v":8,"t":"njegov sin Elkana, njegov sin Ebjasaf, njegov sin Asir;"},{"v":9,"t":"njegov sin Tahat, njegov sin Uriel, njegov sin Uzija, njegov sin Šaul."},{"v":10,"t":"Elkanini sinovi: Amasaj i Ahimot;"},{"v":11,"t":"njegov sin Elkana, njegov sin Sufaj, njegov sin Nahat;"},{"v":12,"t":"njegov sin Eliab, njegov sin Jeroham, njegov sin Elkana. Elkanini sinovi:"},{"v":13,"t":"Samuel, njegov prvenac, drugi Abija."},{"v":14,"t":"Merarijevi sinovi: Mahli, njegov sin Libni, njegov sin Šimej, njegov sin Uza,"},{"v":15,"t":"njegov sin Šima, njegov sin Hagija, njegov sin Asaja."},{"v":16,"t":"Ovo su oni koje je postavio David da se brinu za pjevanje u Domu Jahvinu kad je Kovčeg ondje našao svoje počivalište;"},{"v":17,"t":"oni koji su služili pred Prebivalištem, Šatorom sastanka, pjevajući, dok nije Salomon sagradio Dom Jahvin u Jeruzalemu i koji su obavljali službu po propisanom redoslijedu."},{"v":18,"t":"Evo onih što su obavljali službu i njihovih sinova: od Kehatovih sinova: pjevač Heman, sin Joela, sina Samuela,"},{"v":19,"t":"sina Elkane, sina Jerohama, sina Eliela, sina Toaha,"},{"v":20,"t":"sina Sifa, sina Elkane, sina Mahata, sina Amasaja,"},{"v":21,"t":"sina Elkane, sina Joela, sina Azarje, sina Sefanije,"},{"v":22,"t":"sina Tahata, sina Asira, sina Abjasafa, sina Koraha,"},{"v":23,"t":"sina Jishara, sina Kehata, sina Levija, sina Izraelova."},{"v":24,"t":"Brat mu Asaf stajao je s desne strane; Asaf je bio sin Berekje, sina Šime,"},{"v":25,"t":"sina Mihaela, sina Baaseja, sina Malkije,"},{"v":26,"t":"sina Etnija, sina Zeraha, sina Adaje,"},{"v":27,"t":"sina Etana, sina Zime, sina Šimeja,"},{"v":28,"t":"sina Jahata, sina Geršoma, sina Levijeva."},{"v":29,"t":"Merarijevi sinovi, njihova braća, stajala su mu s lijeve strane: Etan, sin Kušija, sina Abdija, sina Maluka,"},{"v":30,"t":"sina Hašabje, sina Amasje, sina Hilkije,"},{"v":31,"t":"sina Amsija, sina Banija, sina Šomera,"},{"v":32,"t":"sina Mahlija, sina Mušija, sina Merarija, sina Levijeva."},{"v":33,"t":"Njihova braća leviti bili su postavljeni za svu službu u svetom Prebivalištu, u Domu Božjem."},{"v":34,"t":"Aron i njegovi sinovi prinosili su kad na žrtveniku za paljenice i na kadionom žrtveniku, obavljajući sav posao u Svetinji nad svetinjama i izvršujući obred pomirenja nad Izraelom, prema svemu što je zapovjedio Božji sluga Mojsije."},{"v":35,"t":"Ovo su Aronovi sinovi: sin mu Eleazar, njegov sin Pinhas, njegov sin Abišua,"},{"v":36,"t":"njegov sin Buki, njegov sin Uzi, njegov sin Zerahja,"},{"v":37,"t":"njegov sin Merajot, njegov sin Amarja, njegov sin Ahitub,"},{"v":38,"t":"njegov sin Sadok, njegov sin Ahimaas."},{"v":39,"t":"Ovo su im boravišta po naseljima u njihovu području: Aronovim sinovima od Kehatove obitelji - jer na njih je pao ždrijeb -"},{"v":40,"t":"dali su Hebron u judejskoj zemlji s pašnjacima oko njega."},{"v":41,"t":"Gradsko polje i njegova sela dali su Jefuneovu sinu Kalebu."},{"v":42,"t":"Dali su, dakle, Aronovim sinovima gradove-utočišta Hebron i Libnu s pašnjacima, Jatir i Eštemou s pašnjacima,"},{"v":43,"t":"Hilez s pašnjacima, Debir s pašnjacima,"},{"v":44,"t":"Ašan s pašnjacima i Bet Šemeš s pašnjacima."},{"v":45,"t":"Od Benjaminova plemena: Gebu s pašnjacima, Alemet s pašnjacima i Anatot s pašnjacima; dakle trinaest gradova po njihovim rodovima."},{"v":46,"t":"Ostalim Kehatovim sinovima prema plemenskim rodovima pripalo je ždrijebom deset gradova od polovine Manašeova plemena."},{"v":47,"t":"Geršomovim sinovima po njihovim rodovima pripalo je od Jisakarova plemena, od Ašerova plemena, od Naftalijeva plemena i od Manašeova plemena u Bašanu trinaest gradova."},{"v":48,"t":"Merarijevim sinovima po njihovim rodovima pripalo je ždrijebom od Rubenova plemena, od Gadova plemena i od Zebulunova plemena dvanaest gradova."},{"v":49,"t":"Tako su Izraelovi sinovi dali levitima te gradove s pašnjacima."},{"v":50,"t":"Dali su ždrijebom od plemena Judinih sinova, od plemena Šimunovih sinova i od plemena Benjaminovih sinova te gradove koje su spomenuli poimence."},{"v":51,"t":"Onima koji su bili od rodova Kehatovih sinova te dobili ždrijebom gradove od Efrajimova plemena"},{"v":52,"t":"dali su kao gradove-utočišta Šekem s pašnjacima u Efrajimovoj gori i Gezer s pašnjacima,"},{"v":53,"t":"Jokmeam s pašnjacima, Bet Horon s pašnjacima,"},{"v":54,"t":"Ajalon s pašnjacima i Gat-Rimon s pašnjacima."},{"v":55,"t":"Od polovine Manašeova plemena dali su rodovima ostalih Kehatovih sinova: Aner s pašnjacima i Bileam s pašnjacima."},{"v":56,"t":"Geršomovim sinovima dali su od rodova polovine Manašeova plemena Golan u Bašanu s pašnjacima i Aštarot s pašnjacima."},{"v":57,"t":"Od Jisakarova plemena Kedeš s pašnjacima, Dobrat s pašnjacima,"},{"v":58,"t":"Ramot s pašnjacima i Anem s pašnjacima."},{"v":59,"t":"Od Ašerova plemena Mašal s pašnjacima, Abdon s pašnjacima,"},{"v":60,"t":"Hukok s pašnjacima i Rehob s pašnjacima."},{"v":61,"t":"Od Naftalijeva plemena Kedeš u Galileji s pašnjacima, Hamon s pašnjacima i Kirjatajim s pašnjacima."},{"v":62,"t":"Ostalim Merarijevim sinovima dali su od Zebulunova plemena Rimon s pašnjacima i Tabor s pašnjacima."},{"v":63,"t":"S onu stranu Jordana, prema Jerihonu, na istočnoj strani Jordana, dali su im od Rubenova plemena Beser u pustinji s pašnjacima, Jahsu s pašnjacima,"},{"v":64,"t":"Kedemot s pašnjacima i Mefaat s pašnjacima."},{"v":65,"t":"Od Gadova plemena Ramot u Gileadu s pašnjacima, Mahanajim s pašnjacima,"},{"v":66,"t":"Hešbon s pašnjacima i Jazer s pašnjacima."}]},"7":{"hr":[{"v":1,"t":"Jisakarovi su sinovi bili Tola i Fua, Jašub i Šimron, njih četvorica."},{"v":2,"t":"Tolini sinovi: Uzi, Refaja, Jeriel, Jahmaj, Jibsam i Samuel, glavari obitelji od Tole, hrabri junaci svrstani po srodstvu; bilo ih je na broju za Davidova vremena dvadeset i dvije tisuće i šest stotina."},{"v":3,"t":"Uzijevi sinovi: Jizrahja; Jizrahjini sinovi: Mihael, Obadja, Joel i Jišija, u svemu pet glavara."},{"v":4,"t":"S njima je po obiteljima srodnih bilo u vojnim četama za rat trideset i šest tisuća ljudi, jer su imali mnogo žena i sinova."},{"v":5,"t":"Njihove braće po svim Jisakarovim rodovima, hrabrih junaka, bilo je svega osamdeset i sedam tisuća i svi su bili popisani u plemenskim rodovnicima."},{"v":6,"t":"Benjaminovi sinovi: Bela, Beker i Jediael, njih trojica."},{"v":7,"t":"Belini sinovi: Esbon, Uzi, Uziel, Jerimot i Iri, pet obiteljskih glavara, hrabrih junaka; u plemenskom popisu bilo je zapisanih dvadeset dvije tisuće i trideset četiri."},{"v":8,"t":"Bekerovi sinovi: Zimra, Joaš, Eliezer, Elijoenaj, Omri, Jerimot, Abija, Anatot i Alamet, svi Bekerovi sinovi."},{"v":9,"t":"U plemenskom popisu po koljenima, po obiteljskim glavarima, hrabrih junaka, bilo je zapisano dvadeset tisuća i dvije stotine."},{"v":10,"t":"Jediaelovi sinovi: Bilhan, Bilhanovi sinovi: Jeuš, Benjamin, Ahud, Kenaana, Zetan, Taršiš i Ahišahar."},{"v":11,"t":"Svih Jediaelovih sinova po obiteljskim glavarima, hrabrih junaka, bilo je sedamnaest tisuća i dvije stotine, sve za rat sposobnih."},{"v":12,"t":"Šupim i Hupim. Sinovi Irovi: Hušim; njegov sin Aher."},{"v":13,"t":"Naftalijevi sinovi: Jahasiel, Guni, Jeser i Šalum. Bilhini sinovi."},{"v":14,"t":"Manašeovi sinovi: Asriel, koga je rodila Manašeova inoča Aramejka; ona je rodila i Makira, Gileadova oca."},{"v":15,"t":"Makir je oženio Hupima i Šupima; sestra mu se zvala Maaka; ime drugome bilo je Selofhad, a Selofhad je imao kćeri."},{"v":16,"t":"Makirova žena Maaka rodila je sina, komu je nadjela ime Pereš. Bratu mu je dala ime Šareš, a njegovi su sinovi bili Ulam i Rakem."},{"v":17,"t":"Ulamovi sinovi: Bedan. To su sinovi Gileada, sina Makira, Manašeova sina."},{"v":18,"t":"Njegova sestra Hamoleketa rodila je Išhoda, Abiezera i Mahlu."},{"v":19,"t":"Šemidini su sinovi bili: Ahjan, Šekem, Likhi i Aniam."},{"v":20,"t":"Efrajimovi sinovi: Šutelah, njegov sin Bered, njegov sin Tahat, njegov sin Elada, njegov sin Tahat,"},{"v":21,"t":"njegov sin Zabad, njegov sin Šutelah, Ezer i Elad. Njih su ubili gatski građani, rođeni u zemlji, jer su sišli da im otmu stoku."},{"v":22,"t":"Zato je njihov otac Efrajim tugovao dugo vremena, a braća su mu odlazila da ga tješe."},{"v":23,"t":"Onda je ušao k svojoj ženi i ona je zatrudnjela i rodila sina, a on mu nadjenu ime Berija, jer se nesreća dogodila u njegovoj kući."},{"v":24,"t":"Kći mu je bila Šeera, koja je sagradila Donji i Gornji Bet Horon i Uzen Šeeru."},{"v":25,"t":"Sin mu je bio Refah i Rešef, njegov sin Telah, njegov sin Tahan,"},{"v":26,"t":"njegov sin Ladan, njegov sin Amihud, njegov sin Elišama,"},{"v":27,"t":"njegov sin Nun, njegov sin Jošua."},{"v":28,"t":"Njihov posjed i njihova naselja bili su Betel i njegova sela, s istoka Naaran, sa zapada Gazer i njegova sela, Šekem i njegova sela do Gaze s njezinim selima."},{"v":29,"t":"U rukama Manašeovih sinova bio je Bet Šean sa svojim selima, Tanak sa svojim selima, Megido sa svojim selima, Dor sa svojim selima. U njima su živjeli sinovi Izraelova sina Josipa."},{"v":30,"t":"Ašerovi su sinovi bili: Jimna, Jišva, Jišvi i Berija, i njihova sestra Seraha."},{"v":31,"t":"Berijini sinovi: Heber i Malkiel; on je bio Birzajitov otac."},{"v":32,"t":"Heber postade otac Jafletu, Šomeru, Hotamu i njihovoj sestri Šui."},{"v":33,"t":"Jafletovi su sinovi bili: Pasak, Bimhal i Ašvat; to su bili Jafletovi sinovi."},{"v":34,"t":"A sinovi njegova brata Šomera: Rohga, Huba i Aram."},{"v":35,"t":"Sinovi njegova brata Helema: Sofah, Jimna, Šeleš i Amal."},{"v":36,"t":"Sofahovi sinovi: Suah, Harnefer, Šual, Beri, Jimra,"},{"v":37,"t":"Beser, Hod, Šama, Šilša, Jitran i Bera."},{"v":38,"t":"Jeterovi sinovi: Jefune, Fispa i Ara."},{"v":39,"t":"Ulini sinovi: Arah, Haniel i Risja."},{"v":40,"t":"Svi su oni bili Ašerovi sinovi, obiteljski glavari, probrani hrabri junaci, glavari među knezovima; kad su bili popisani, bilo ih je dvadeset i šest tisuća ljudi u bojnim četama."}]},"8":{"hr":[{"v":1,"t":"Benjamin rodi prvenca Belu, drugog Ašbela, trećeg Ahraba,"},{"v":2,"t":"četvrtog Nohu i petog Rafu."},{"v":3,"t":"Belini su sinovi bili: Adar, Gera, Ehudov otac,"},{"v":4,"t":"Abišua, Naaman, Ahoah,"},{"v":5,"t":"Gera, Šefufan i Huram."},{"v":6,"t":"Oni su bili Ehudovi sinovi i bili su obiteljski glavari onima koji su živjeli u Gebi, odakle su ih odveli u sužanjstvo u Manahat;"},{"v":7,"t":"Naaman, Ahija i Gera; on ih je vodio u sužanjstvo i rodio Uzu i Ahihuda."},{"v":8,"t":"Šaharajim, pošto je otpustio žene Hušimu i Baru, dobio je sinove u Moapskom polju:"},{"v":9,"t":"sa svojom ženom Hodešom imao je sinove Jobaba, Sibju, Mešu, Malkama,"},{"v":10,"t":"Jeusa, Sakju i Mirmu; to su bili njegovi sinovi, obiteljski glavari."},{"v":11,"t":"S Hušimom je rodio Abituba i Elpaala."},{"v":12,"t":"Elpaalovi su sinovi bili: Eber, Mišam i Šamed; on je sagradio Ono i Lod s njihovim selima."},{"v":13,"t":"Zatim Berija i Šema. Oni su bili obiteljski glavari onima koji su živjeli u Ajalonu i istjerali su gatske stanovnike."},{"v":14,"t":"Njegov brat: Šešak. Jeremot,"},{"v":15,"t":"Zabadja, Arad i Eder,"},{"v":16,"t":"Mihael, Jišpa i Joha bili su Berijini sinovi."},{"v":17,"t":"Zebadja, Mešulam, Hizki, Haber,"},{"v":18,"t":"Jišmeraj, Jizlia i Jobab bili su Elpaalovi sinovi."},{"v":19,"t":"Jakim, Zikri, Zabdi,"},{"v":20,"t":"Elijoenaj, Siltaj, Eliel,"},{"v":21,"t":"Adaja, Beraja i Šimrat bili su Šimijevi sinovi."},{"v":22,"t":"Jišpan, Eber, Eliel,"},{"v":23,"t":"Abdon, Zikri, Hanan,"},{"v":24,"t":"Hananija, Elam, Antotija,"},{"v":25,"t":"Jifdeja, Fenuel bili su Šešakovi sinovi."},{"v":26,"t":"Šamšeraj, Šeharja, Atalija,"},{"v":27,"t":"Jaarešja, Elija i Zikri bili su Jerohamovi sinovi."},{"v":28,"t":"To su bili glavari obitelji svrstanih po koljenima. Živjeli su u Jeruzalemu."},{"v":29,"t":"U Gibeonu su živjeli: praotac Gibeon, čija se žena zvala Maaka."},{"v":30,"t":"Njegov je sin prvenac bio Abdon, pa Sur, Kiš, Baal, Nadab,"},{"v":31,"t":"Gedor, Ahjo, Zaker,"},{"v":32,"t":"i Miklot, koji je rodio Šimu; pa su i oni živjeli kod svoje braće u Jeruzalemu, sa svojom braćom."},{"v":33,"t":"Ner rodi Kiša, a Kiš rodi Šaula, Šaul rodi Jonatana, Malki-Šua, Abinadaba, Ešbaala,"},{"v":34,"t":"Jonatanov je sin bio Merib Baal; Merib Baal rodi Miku."},{"v":35,"t":"Mikini su sinovi bili: Piton, Melek, Tarea i Ahaz."},{"v":36,"t":"Ahaz rodi Joadu; Joada rodi Alemeta, Azmaveta i Zimrija; Zimri rodi Mosu."},{"v":37,"t":"Mosa rodi Biniju, čiji je sin bio Rafa, a njegov sin Elasa, njegov sin Asel."},{"v":38,"t":"Asel je imao šest sinova, kojima su imena: Azrikam, njegov prvenac, Bokru, Jišmael, Šearja, Obadja i Hanan; svi su oni bili Aselovi sinovi."},{"v":39,"t":"Sinovi njegova brata Ešeka bili su: Ulam, prvenac mu, drugi Jehuš, treći Elifelet."},{"v":40,"t":"Ulamovi su sinovi bili hrabri junaci koji su zapinjali luk i imali mnogo sinova i unuka, sto pedeset. Svi su oni bili od Benjaminovih sinova."}]},"9":{"hr":[{"v":1,"t":"Svi su Izraelci bili upisani u plemenskim rodovnicima, a zapisani su i u Knjizi izraelskih kraljeva. A Judejci su zbog nevjere bili odvedeni u sužanjstvo u Babilon."},{"v":2,"t":"Prvi su stanovnici na svojem posjedu i u svojim gradovima bili Izraelci, svećenici, leviti i netinci."},{"v":3,"t":"U Jeruzalemu su živjeli ljudi od Judinih sinova, od Benjaminovih sinova, od Efrajimovih i Manašeovih sinova, i to:"},{"v":4,"t":"Utaj, sin Amihuda, sina Omrija, sina Imrija, sina Banija, od sinova Judina sina Peresa."},{"v":5,"t":"Od Šilonaca: Asaja, prvenac, sa svojim sinovima."},{"v":6,"t":"Od Zarehovih sinova: Jeuel i njegova braća, šest stotina i devedeset."},{"v":7,"t":"Od Benjaminovih sinova Salu, sin Mešulama, sina Hodavje, Hasenuina sina;"},{"v":8,"t":"Ibneja, Jerohamov sin, i Ela, sin Uzije, Mokrijeva sina, i Mešulam, sin Šefatje, sina Reuela, Ibnijina sina."},{"v":9,"t":"Imali su po svojim rodovima devet stotina pedeset i šestero braće. Svi su oni bili glavari, svaki svoga roda."},{"v":10,"t":"Od svećenika: Jedaja, Jojarib i Jakin,"},{"v":11,"t":"Azarja, sin Hilkije, sina Mešulama, sina Sadoka, sina Merajota, Ahitubova sina, predstojnik Doma Božjeg."},{"v":12,"t":"Adaja, sin Jerohama, sina Pašhura, Malkijina sina, Masaj, sin Adiela, sina Jahzere, sina Mešulama, sina Mešilemita, Imerova sina."},{"v":13,"t":"Njihove braće, glava obitelji, boraca što su obavljali službu u Domu Božjem, bilo je tisuću sedam stotina i šezdeset."},{"v":14,"t":"Od levita Šemaja, sin Hašuba, sin Azrikama, Hašabjina sina, između Merarijevih sinova;"},{"v":15,"t":"Bakbakar, Hereš, Galal i Matanija, sin Mike, sina Zikrija, Asafova sina;"},{"v":16,"t":"Obadja, sin Šemaje, sina Galala, Jedutunova sina, i Berekja, sin Ase, Elkanina sina, koji je živio u Netofatskim selima."},{"v":17,"t":"Vratari: Šalum, Akub, Talmon i Ahiman, i njihova braća; Šalum je bio poglavar,"},{"v":18,"t":"i dosad je bio na kraljevskim vratima prema istoku. Oni su bili vratari po četama levita."},{"v":19,"t":"Šalum, sin Korea, sina Abjasafa, Korahova sina, sa svojom braćom Korahovcima iz njihove obitelji, bili su odgovorni za bogoslužje; oni su čuvali pragove Šatora, dok su njihovi oci čuvali ulaz u Jahvin tabor."},{"v":20,"t":"Eleazarov sin Pinhas bio je predstojnik nad njima nekada (Jahve bio s njim!)."},{"v":21,"t":"Mešelemjin sin Zaharija bio je vratar na vratima Šatora sastanka."},{"v":22,"t":"Svih izabranih vratara pragova bilo je dvjesta i dvanaest. Bili su upisani u rodovnike u svojim selima. Postavili su ih u službu David i vidjelac Samuel zbog njihove vjernosti."},{"v":23,"t":"Oni i njihovi sinovi čuvali su stražu na vratima Doma Jahvina, Doma Šatora."},{"v":24,"t":"Vratari su stajali na četiri strane: na istoku, na zapadu, na sjeveru i na jugu."},{"v":25,"t":"Njihova braća po selima dolazila su od vremena do vremena da im se pridruže po sedam dana."},{"v":26,"t":"Samo su četiri vratarska predstojnika bila neprestano u službi. Bili su leviti, postavljeni nad sobama i nad riznicama Božjega Doma."},{"v":27,"t":"Noćivali su oko Božjega Doma jer im je bila dužnost da stražare i da otključavaju svako jutro."},{"v":28,"t":"Neki su od njih bili odgovorni za bogoslužno posuđe. Prebrojavali su ga kad bi ga unosili i kad bi ga iznosili."},{"v":29,"t":"Neki su se od njih brinuli za pokućstvo, sve posvećene stvari, fino brašno, vino, ulje, tamjan i miomirise;"},{"v":30,"t":"a neki od svećeničkih sinova miješali su pomast od miomirisa."},{"v":31,"t":"Matitja, jedan od levita, prvenac Šaluma Korahovca, brinuo se za stvari koje se peku na tavi."},{"v":32,"t":"Neki od Kehatovaca, njihove braće, bili su odgovorni za kruhove što se postavljaju svake subote."},{"v":33,"t":"Oni su bili i pjevači, glavari levitskih obitelji. Kad su bili slobodni, živjeli su u hramskih sobama, jer su dan i noć bili na dužnosti."},{"v":34,"t":"To su bili glavari levitskih obitelji prema svom srodstvu. Ti su poglavari živjeli u Jeruzalemu."},{"v":35,"t":"U Gibeonu su živjeli: Gibeonov otac Jeiel, čijoj je ženi bilo ime Maaka."},{"v":36,"t":"Sin mu je prvenac bio Abdon, pa Sur, Kiš, Baal, Ner, Nadab,"},{"v":37,"t":"Gedor, Ahjo, Zaharija i Miklot."},{"v":38,"t":"Miklot rodi Šimeama. I oni su živjeli u Jeruzalemu, naprama svojoj braći."},{"v":39,"t":"Ner rodi Kiša; a Kiš rodi Šaula; Šaul rodi Jonatana, Malki-Šuu, Abinadaba i Ešbaala."},{"v":40,"t":"Jonatanov je sin bio Merib Baal. Merib Baal rodi Miku."},{"v":41,"t":"Mikini su sinovi bili: Piton, Melek, Tahrea i Ahaz."},{"v":42,"t":"Ahaz rodi Jaru; Jara rodi Alemeta, Azmaveta i Zimrija; Zimri rodi Mosu."},{"v":43,"t":"Mosa rodi Binu; njegov je sin bio Rafaja, njegov sin Elasa, njegov sin Asel."},{"v":44,"t":"Asel je imao šest sinova, kojima su imena: Azrikam, Bokru, Jišmael, Šearja, Obadja i Hanan; to su Aselovi sinovi."}]},"10":{"hr":[{"v":1,"t":"Filistejci su zavojštili na Izraelce. Izraelci su pobjegli pred njima i padali pobijeni po gori Gilboi."},{"v":2,"t":"Filistejci stisnuše Šaula i njegove sinove i pogubiše Šaulove sinove Jonatana, Abinadaba i Malki-Šuu."},{"v":3,"t":"Boj je postao žešći oko Šaula. Iznenadiše ga strijelci s lukovima i on pade ranjen od strijelaca."},{"v":4,"t":"Tada Šaul reče svome štitonoši: “Izvuci svoj mač i probodi me da ne dođu ti neobrezanci i ne narugaju mi se.” Ali se njegov štitonoša prestravi i ne htjede toga učiniti. Zato Šaul uze mač i baci se na nj."},{"v":5,"t":"Kad je štitonoša vidio da je Šaul umro, baci se i on na svoj mač i umrije s njim."},{"v":6,"t":"Tako onog dana pogiboše zajedno Šaul, njegova tri sina i sav njegov dom."},{"v":7,"t":"Kad su svi Izraelci koji su bili u dolini vidjeli da su sinovi Izraelovi pobjegli i da je poginuo Šaul sa sinovima, ostavili su svoje gradove i razbježali se. Filistejci dođoše i nastaniše se u njima."},{"v":8,"t":"Kad su sutradan došli Filistejci da oplijene pobijene, našli su Šaula s njegovim sinovima gdje leže mrtvi na gori Gilboi."},{"v":9,"t":"Svukavši ga, uzeše mu glavu i oružje te poslaše po filistejskoj zemlji unaokolo javljajući veselu vijest svojim idolima i narodu."},{"v":10,"t":"Potom su oružje metnuli u hram svoga boga, a lubanju mu izložili u Dagonovu hramu."},{"v":11,"t":"Kad su čuli svi Jabeš-Gileađani što su Filistejci učinili od Šaula,"},{"v":12,"t":"ustali su svi hrabri ljudi i uzeli Šaulovo mrtvo tijelo i tjelesa njegovih sinova i, donijevši ih u Jabeš, pokopali su njihove kosti pod tamarisom u Jabešu; i postiše sedam dana."},{"v":13,"t":"Tako je poginuo Šaul za svoju nevjeru kojom se iznevjerio Jahvi: nije držao Jahvine zapovijedi i povrh toga je pitao za savjet bajačicu,"},{"v":14,"t":"a nije pitao Jahvu; zato ga je ubio i prenio kraljevstvo na Jišajeva sina Davida."}]},"11":{"hr":[{"v":1,"t":"Tada se sabraše svi Izraelci k Davidu u Hebron i rekoše: “Evo, mi smo od tvoje kosti i tvojeg mesa."},{"v":2,"t":"Još prije, dok je Šaul bio kralj, ti si upravljao svim pokretima Izraela; Jahve, tvoj Bog, rekao ti je: 'Ti ćeš pasti moj izraelski narod i ti ćeš biti knez nad mojim narodom Izraelom.'”"},{"v":3,"t":"Tako dođoše sve izraelske starješine kralju u Hebron, a kralj David s njima sklopi savez u Hebronu pred Jahvom i pomazaše Davida za kralja nad Izraelom, kako bijaše Jahve rekao Samuelu."},{"v":4,"t":"Onda je otišao David sa svim Izraelom na Jeruzalem, a to je Jebus, jer su ondje bili Jebusejci i živjeli su u onoj zemlji."},{"v":5,"t":"Ali su Jebusejci poručili Davidu: “Nećeš ući ovamo!” Ipak David osvoji Sionsku tvrđavu, to jest Davidov grad."},{"v":6,"t":"Jer je David rekao: “Tko prvi porazi Jebusejce, bit će vrhovni vojvoda i knez.” Prvi se popeo Sarvijin sin Joab i postao vojvoda."},{"v":7,"t":"Tada se David nastanio u toj tvrđavi; zato su je prozvali Davidovim gradom."},{"v":8,"t":"Sazidao je tada grad unaokolo, od Milona do ograde, a Joab je obnovio ostali dio grada."},{"v":9,"t":"David je postajao sve silniji, jer je Jahve nad vojskama bio s njim."},{"v":10,"t":"Evo vojvoda Davidovim junacima koji su junački radili uza nj za njegovo kraljevstvo sa svim Izraelom da ga po Jahvinoj riječi zakralje nad Izraelom."},{"v":11,"t":"Evo popisa Davidovih junaka: Hakmonijev sin Jašobam, glavar nad tridesetoricom; on je mahnuo svojim kopljem na tri stotine i pobio ih odjednom."},{"v":12,"t":"Za njim Dodonov sin Eleazar, Ahošanin, jedan između tri junaka."},{"v":13,"t":"On je bio s Davidom u Pas Damimu, kad su se Filistejci skupili na boj, a ondje je bilo polje puno ječma; kad je narod počeo bježati ispred Filistejaca,"},{"v":14,"t":"oni su stali usred toga polja i obranili ga pobivši Filistejce. Tako im Jahve dade veliku pobjedu."},{"v":15,"t":"Trojica su između tridesetorice jednom sišla do hridi k Davidu u Adulamsku pećinu kad su filistejske čete stajale u taboru u Refaimskoj dolini."},{"v":16,"t":"David je tada bio u svojoj kuli, a filistejska je posada tada bila u Betlehemu."},{"v":17,"t":"David uzdahnu: “O kad bi me tko napojio vodom iz betlehemskoga studenca što je kod vrata!”"},{"v":18,"t":"Tada ta trojica prodriješe kroz filistejski tabor i, zahvativši vode iz betlehemskoga studenca što je kod vrata, donesoše je i dadoše Davidu. Ali je David ne htjede piti nego je proli kao ljevanicu Jahvi"},{"v":19,"t":"govoreći: “Ne dao mi moj Bog da to učinim! Zar da pijem krv ovih ljudi? TÓa izlažući život pogibli donijeli su vode.” I nije htio piti. To su, eto, učinila ta tri junaka."},{"v":20,"t":"Abišaj, Joabov brat, bio je vojvoda nad tridesetoricom; on je vitlao kopljem na tri stotine, pobio ih i proslavio se među tridesetoricom."},{"v":21,"t":"Bio je među trojicom ugledniji od druge dvojice i bio im vojvoda, ali prve trojice nije dostigao."},{"v":22,"t":"Jojadin sin Benaja, junak iz Kabseela, bogat junačkim djelima, ubio je dva sina Ariela iz Moaba; on je jednoga snježnog dana sišao i ubio lava usred jame."},{"v":23,"t":"Ubio je i nekog Egipćanina, čovjeka od pet lakata. Egipćanin je imao u ruci koplje kao tkalačko vratilo, a on je izišao preda nj sa štapom i, istrgavši Egipćaninu koplje iz ruke, ubio ga njegovim kopljem."},{"v":24,"t":"To je učinio Jojadin sin Benaja i proslavio se imenom među ona tri junaka."},{"v":25,"t":"Bio je najznamenitiji među tridesetoricom, ali one prve trojice nije dostigao. David ga postavi za zapovjednika svoje tjelesne straže."},{"v":26,"t":"Hrabri su junaci bili: Joabov brat Asahel, Dodonov sin Elhanan iz Betlehema,"},{"v":27,"t":"Haroranin Šamot, Pelonjanin Heles;"},{"v":28,"t":"Akešov sin Ira, Tekoanin, Abiezer Anatoćanin;"},{"v":29,"t":"Sibkaj Hušaćanin, Ilaj Ahošanin;"},{"v":30,"t":"Mahraj Netofaćanin, Baanin sin Heled, Netofaćanin;"},{"v":31,"t":"Ribajev sin Itaj iz Gibeata sinova Benjaminovih, Benaja Piratonjanin;"},{"v":32,"t":"Huraj iz Gaaških potoka, Abiel Arbaćanin;"},{"v":33,"t":"Azmavet Bahurimljanin, Eljahba Šaalbonjanin."},{"v":34,"t":"Sinovi Hašema Gizonjanina: Sagejin sin Jonatan, Hararanin;"},{"v":35,"t":"Sakarov sin Ahiam, Hararanin, Urov sin Elipal;"},{"v":36,"t":"Hefer Mekeranin, Ahija Pelonjanin;"},{"v":37,"t":"Hesro Karmelac, Ezbajev sin Naaraj;"},{"v":38,"t":"Natanov brat Joel, Hagrijev sin Mibhar;"},{"v":39,"t":"Amonac Selek, Beroćanin Nahraj, štitonoša Sarvijina sina Joaba;"},{"v":40,"t":"Ira Jitranin, Gareb Jitranin;"},{"v":41,"t":"Urija Hetit, Ahlajev sin Zabad;"},{"v":42,"t":"Šizin sin Adina, Rubenovac, vojvoda Rubenova plemena, i s njime tridesetorica."},{"v":43,"t":"Maakin sin Hanan i Jošafat Mitnjanin."},{"v":44,"t":"Uzija Aštaroćanin, Šama i Jeiel, sinovi Aroerca Hotama;"},{"v":45,"t":"Šimrijev sin Jediael i njegov brat Joha Tišanin."},{"v":46,"t":"Mahavac Eliel i Elnaamovi sinovi Jeribaj i Jošavja i Moabac Jitma;"},{"v":47,"t":"Eliel i Obed i Mesobajanin Jaasiel."}]},"12":{"hr":[{"v":1,"t":"Evo onih što dođoše k Davidu u Siklag dok se još uklanjao od Kiševa sina Šaula i bili su mu među junacima pomagači u boju;"},{"v":2,"t":"umjeli su rukovati lukom i desnicom i ljevicom i znali se služiti kamenjem i strijelama. Između Šaulove braće, Benjaminovaca:"},{"v":3,"t":"vojvoda Ahiezer i Joaš, sinovi Gibeanca Šemaje, pa Jeziel i Pelet, Azmavetovi sinovi, i Beraka i Jehu Anatoćanin;"},{"v":4,"t":"Gibeonac Išmaja, junak među tridesetoricom i nad tridesetoricom,"},{"v":5,"t":"Jeremija, Jahaziel, Johanan i Jozabad Gederoćanin;"},{"v":6,"t":"Eluzaj, Jerimot, Bealja, Šemarja i Šefatja Harufejac;"},{"v":7,"t":"Elkana, Jišija, Azarel, Joezer i Jašobam Korhinjani,"},{"v":8,"t":"Joel i Zebadja, sinovi Jerohama Gedorca."},{"v":9,"t":"Neki su Gadovci prešli k Davidu u tvrđavu u pustinju, hrabri junaci, ratnici vješti boju, naoružani štitom i kopljem; lica im bijahu kao lavovska, a brzi bijahu kao gazele po gorama:"},{"v":10,"t":"vojvoda Ezer, drugi Obadja, treći Eliab;"},{"v":11,"t":"četvrti Mišmana, peti Jeremija,"},{"v":12,"t":"šesti Ataj, sedmi Eliel;"},{"v":13,"t":"osmi Johanan, deveti Elzabad,"},{"v":14,"t":"deseti Jeremija, jedanaesti Makbanaj."},{"v":15,"t":"To su bile od Gadovih sinova vojne starješine, najmanji nad stotinom, a najveći nad tisućom."},{"v":16,"t":"To su oni koji su prvoga mjeseca prešli preko Jordana kad se razlio preko svih svojih obala i koji su rastjerali sve stanovnike iz dubokih dolina na istok i na zapad."},{"v":17,"t":"Došli su i od Benjaminovih i Judinih sinova k Davidu u tvrđavu."},{"v":18,"t":"David je izašao pred njih i, progovorivši, rekao im: “Ako dolazite s mirom k meni da mi pomognete, moje će se srce ujediniti s vama; ako li ste došli da me izdate mojim neprijateljima, neka Bog naših otaca vidi i neka osudi, jer nema nepravde na mojim rukama!”"},{"v":19,"t":"Tada duh obuze Amasaja, vojvodu nad tridesetoricom, i on reče: “Tebi, Davide! S tobom, sine Jišajev, mir! Mir s tobom, mir s onim tko ti pomaže, jer tvoj pomoćnik jest tvoj Bog!” Tako ih je David primio i postavio ih među vojvode nad četama."},{"v":20,"t":"Od Manašeovih su sinova neki prešli k Davidu kad je išao s Filistejcima na Šaula u boj, ali im nije pomogao, jer su ga filistejski knezovi, dobro promislivši, otpustili govoreći: “Mogao bi prijeći k svome gospodaru Šaulu, a to bi nas stajalo glava.”"},{"v":21,"t":"Kad se, dakle, vraćao u Siklag, prešli su k njemu od Manašeova plemena: Adna, Jozabad, Jedael, Mihael, Jozabad, Elihu i Siltaj, glavari tisućnici u Manašeovu plemenu."},{"v":22,"t":"Oni su pomagali Davidu protiv razbojničkih četa jer su svi bili hrabri junaci te su postali zapovjednici u njegovoj vojsci."},{"v":23,"t":"Iz dana u dan odista su dolazili k Davidu da mu pomažu, sve dok njegov tabor ne postade divovski, kao Božji tabor."},{"v":24,"t":"Evo broja ljudi naoružanih za rat koji su došli k Davidu u Hebron da Šaulovo kraljevstvo prenesu na nj po Jahvinoj zapovijedi:"},{"v":25,"t":"Judinih sinova, koji su nosili štit i koplje, šest tisuća i osam stotina naoružanih za rat."},{"v":26,"t":"Od Šimunovih sinova, hrabrih junaka za rat, sedam tisuća i sto."},{"v":27,"t":"Od Levijevih sinova četiri tisuće i šest stotina."},{"v":28,"t":"Tako i Jojada, poglavar Aronovim potomcima, i s njim tri tisuće i sedam stotina;"},{"v":29,"t":"i mladi Sadok, hrabar junak, i od njegova roda dvadeset i dva kneza."},{"v":30,"t":"A od Benjaminovih sinova, Šaulove braće, tri tisuće, jer ih je dotad najveći dio još ostao vjeran Šaulovoj kući."},{"v":31,"t":"Efrajimovih sinova dvadeset tisuća i osam stotina, sve hrabrih junaka, ljudi na glasu u svojim porodicama."},{"v":32,"t":"Od polovine Manašeova plemena osamnaest tisuća, poimence spomenutih, da dođu da zakralje Davida."},{"v":33,"t":"Od Jisakarovih sinova, koji su umjeli proniknuti svoje vrijeme i spoznati što treba da učini Izrael; njihovih poglavara dvije stotine. Sva su im njihova braća bila podložna."},{"v":34,"t":"Od Zebulunovih sinova, sposobnih za rat i naoružanih za boj svakojakim bojnim oružjem, pedeset tisuća, koji su se odvažna srca vrstali u bojne redove."},{"v":35,"t":"Od Naftalijeva plemena tisuću knezova i s njima trideset i sedam tisuća ljudi sa štitovima i kopljima;"},{"v":36,"t":"od Danova plemena dvadeset i osam tisuća i šest stotina naoružanih za boj,"},{"v":37,"t":"a od Ašerova plemena četrdeset tisuća sposobnih za vojsku i za boj opremljenih."},{"v":38,"t":"Od onih s onu stranu Jordana, od Rubenova, od Gadova i od polovine Manašeova plemena, sto i dvadeset tisuća ljudi sa svakojakim ratnim oružjem."},{"v":39,"t":"Svi ti vojnici, svrstani u bojne redove, dođoše poštena srca u Hebron da zakralje Davida nad svim Izraelom; i svi su ostali Izraelci bili jednodušni da Davida postave za kralja."},{"v":40,"t":"Proveli su s Davidom tri dana, jedući i pijući. Braća sve spremiše za njih."},{"v":41,"t":"Njihovi su najbliži susjedi, sve do Jisakara, Zebuluna i Naftalija, donosili hranu na magarcima, devama i mazgama, a na volovima jela: brašna, smokvenih kolača, suha grožđa, vina, ulja, krupne i sitne stoke izobila, jer je bilo veselje u Izraelu."}]},"13":{"hr":[{"v":1,"t":"David je vijećao s tisućnicima, stotnicima i sa svim vođama."},{"v":2,"t":"I reče on svemu zboru Izraelovu: “Ako vam je pravo te ako je naš Bog Jahve odlučio tako, poslat ćemo glasnike k svojoj ostaloj braći u svim izraelskim zemljama, a tako i svećenicima s njima i levitima po gradovima pašnjaka njihovih, da se ujedine s nama."},{"v":3,"t":"Prenijet ćemo k sebi Kovčeg svoga Boga, jer ga nismo doista tražili za Šaulovih dana.”"},{"v":4,"t":"Sav zbor odluči da se tako učini, jer je to bilo pravo u očima svega naroda."},{"v":5,"t":"Tako je David sabrao sav narod Izraelov od Egipatskoga Šihora pa do Ulaza u Hamat da donesu Kovčeg Božji iz Kirjat Jearima."},{"v":6,"t":"Pošao je David sa svim Izraelom u Baalu, u Kirjat Jearim, koji je u Judi, da odande ponesu Kovčeg Božji nazvan imenom Jahve, koji stoluje nad kerubinima."},{"v":7,"t":"Povezli su Kovčeg Božji na novim kolima iz Abinadabove kuće; a Uza i Ahjo upravljali su kolima."},{"v":8,"t":"David i sav Izrael igrali su pred Bogom iz sve snage pjevajući uza zvuke citara, harfa, bubnjeva, cimbala i truba."},{"v":9,"t":"Kad su došli do Kidonova gumna, posegnu Uza rukom da pridrži Kovčeg jer ga volovi umalo ne prevrnuše."},{"v":10,"t":"Ali se Jahve razgnjevio na Uzu i udario ga zato što je pružio ruku prema Kovčegu. Umro je ondje pred Bogom."},{"v":11,"t":"Davidu bijaše žao što je Jahve onako udario Uzu i on prozva ono mjesto Peres Uza, kako se zove i dan-danas."},{"v":12,"t":"Toga se dana David uplaši Boga i reče: “Kako ću donijeti k sebi Kovčeg Božji?”"},{"v":13,"t":"Nije dao svratiti Kovčega k sebi u Davidov grad nego ga skloni u kuću Obed-Edoma Gitejca."},{"v":14,"t":"I ostade Kovčeg Božji kod Obed-Edomove obitelji, u njegovoj kući, tri mjeseca. Jahve stoga blagoslovi Obed-Edomovu kuću i sve što je imao."}]},"14":{"hr":[{"v":1,"t":"Tirski kralj Hiram posla k Davidu izaslanstvo i cedrovih drva, zidara i tesara da mu grade dvor."},{"v":2,"t":"Tada David spozna da ga je Jahve potvrdio za kralja nad Izraelom i da je uzvisio njegovo kraljevstvo radi svojega izraelskog naroda."},{"v":3,"t":"David je uzeo još žena u Jeruzalemu i imao još sinova i kćeri."},{"v":4,"t":"Evo imena djece koja mu se rodiše u Jeruzalemu: Šamua, Šobab, Natan, Salomon,"},{"v":5,"t":"Jibhar, Elišua, Elpalet,"},{"v":6,"t":"Nogah, Nefeg, Jafija,"},{"v":7,"t":"Elišama, Beeljada i Elifelet."},{"v":8,"t":"Kad su Filistejci čuli da su Davida pomazali za kralja nad svim Izraelom, iziđoše svi da se dočepaju Davida. David, čuvši to, iziđe pred njih."},{"v":9,"t":"Filistejci dođoše i raširiše se po Refaimskoj dolini."},{"v":10,"t":"Tada David upita Boga: “Mogu li napasti Filistejce? Hoćeš li ih predati meni u ruke?” Jahve mu odgovori: “Napadni, jer ću ih predati tebi u ruke!”"},{"v":11,"t":"Tada krenuše u Baal Perasim i David ih ondje pobi. David reče: “Bog je prodro među moje neprijatelje mojom rukom, kao što voda prodire.” Stoga se ono mjesto prozvalo Baal Perasim."},{"v":12,"t":"Ostavili su ondje svoje bogove; a David zapovjedi da ih spale."},{"v":13,"t":"Opet se Filistejci raširiše po onoj dolini."},{"v":14,"t":"David opet upita Boga, a Bog mu odgovori: “Ne idi za njima nego ih opkoli i navali na njih s protivne strane Bekaima."},{"v":15,"t":"Pa kad začuješ topot koraka po bekaimskim vrhovima, onda izađi u boj, jer će tada ići Bog pred tobom da pobije filistejsku vojsku.”"},{"v":16,"t":"David učini kako mu je zapovjedio Bog; i pobili su filistejsku vojsku od Gibeona do Gezera."},{"v":17,"t":"Davidovo se ime pročulo po svim zemljama, a Jahve uli strah od njega svim narodima."}]},"15":{"hr":[{"v":1,"t":"Onda je David sazidao dvore u Davidovu gradu, pripravio mjesto za Kovčeg Božji i razapeo mu Šator."},{"v":2,"t":"Potom je rekao David: “Ne smije nositi Kovčeg Božji nitko osim levita, jer je njih izabrao Jahve da nose Kovčeg Jahvin i da mu služe dovijeka.”"},{"v":3,"t":"David je sakupio sav Izrael u Jeruzalem da prenesu Kovčeg Jahvin gore na njegovo mjesto koje mu bijaše pripravio."},{"v":4,"t":"Skupio je David i Aronove sinove i levite."},{"v":5,"t":"Od Kehatovih sinova: kneza Uriela i sto dvadeset njegove braće;"},{"v":6,"t":"od Merarijevih sinova: kneza Asaju i dvjesta dvadeset njegove braće;"},{"v":7,"t":"od Geršomovih sinova: kneza Joela i sto trideset njegove braće."},{"v":8,"t":"Od Elisafanovih sinova: kneza Šemaju i dvjesta njegove braće."},{"v":9,"t":"Od Hebronovih sinova: kneza Eliela i osamdeset njegove braće;"},{"v":10,"t":"od Uzielovih sinova: kneza Aminadaba i sto dvanaest njegove braće."},{"v":11,"t":"Tada David pozva svećenike Sadoka i Ebjatara i levite Uriela, Asaju, Joela, Šemaju, Eliela i Aminadaba,"},{"v":12,"t":"pa im reče: “Vi ste glavari levitskih porodica; posvetite sebe i svoju braću da prenesete gore Kovčeg Jahve, Izraelova Boga, na mjesto koje sam mu pripravio."},{"v":13,"t":"Jer nas je pobio Jahve, Bog naš, zato što prvi put vi niste bili nazočni i što ga nismo tražili onako kako je trebalo.”"},{"v":14,"t":"Posvetiše se tada svećenici i leviti da prenesu gore Kovčeg Jahve, Izraelova Boga."},{"v":15,"t":"Levitski su sinovi ponijeli Božji Kovčeg, na svojim ramenima, o motkama, kako je zapovjedio Mojsije po Jahvinoj riječi."},{"v":16,"t":"Tada David reče levitskim knezovima da između svoje braće postave pjevače s glazbalima, s harfama, citrama i cimbalima da se čuje i da gromko odjekuje radosno pjevanje."},{"v":17,"t":"Leviti su postavili Joelova sina Hemana, a od njegove braće Berekjina sina Asafa, i od njihove braće, Merarijevih sinova, Kušajina sina Etana."},{"v":18,"t":"S njima njihovu braću drugoga reda: Zahariju, sina Jaazielova, Šemiramota, Jehiela, Unija, Eliaba, Benaju, Maaseju, Matitju, Eliflehua, Mikneju, Obed Edoma i Jeiela, vratare."},{"v":19,"t":"A pjevači, Heman, Asaf i Etan gromko su udarali u mjedene cimbale."},{"v":20,"t":"A Zaharija, Uziel, Šemiramot, Jehiel, Uni, Eliab, Maaseja i Benaja u harfe s visokim zvucima;"},{"v":21,"t":"a Matitja, Eliflehu, Mikneja, Obed Edom, Jeiel i Azazja u citre, u osminskoj pratnji."},{"v":22,"t":"Kenanja, knez onih levita koji su nosili Kovčeg, upravljao je prenošenjem jer je bio vješt u tome."},{"v":23,"t":"Berekja i Elkana bili su vratari kod Kovčega."},{"v":24,"t":"Šebanija, Jošafat, Netanel, Amasaj, Zaharija, Benaja i Eliezer, svećenici, trubili su u trube pred Božjim Kovčegom; Obed Edom i Jehija bili su vratari kod Kovčega."},{"v":25,"t":"Tako je David s izraelskim starješinama i tisućnicima radosno išao prenoseći gore Kovčeg saveza Jahvina iz Obed-Edomove kuće."},{"v":26,"t":"Kad je Bog pomogao levitima koji su nosili Kovčeg saveza Jahvina, žrtvovali su sedam junaca i sedam ovnova."},{"v":27,"t":"David bijaše ogrnut plaštem od tanka platna, a tako i svi leviti što su nosili Kovčeg, kao i pjevači i Kenanija koji je upravljao pjevačima. David je imao na sebi lanen oplećak."},{"v":28,"t":"Tako je sav Izrael prenosio gore Kovčeg saveza Jahvina, radosno kličući uz jeku rogova, truba i cimbala, igrajući uza zvuke harfe i citre."},{"v":29,"t":"Kad je Kovčeg saveza Jahvina ulazio u Davidov grad, Šaulova kći Mikala, gledajući s prozora, vidje kralja Davida kako skače i igra i prezre ga ona u svom srcu."}]},"16":{"hr":[{"v":1,"t":"Tada unesoše Kovčeg Božji i postaviše ga usred šatora koji mu bijaše razapeo David. Onda su prinijeli paljenice i pričesnice pred Bogom."},{"v":2,"t":"Pošto je prinio paljenice i pričesnice, David blagoslovi narod Jahvinim imenom."},{"v":3,"t":"Onda razdijeli svim Izraelcima, ljudima i ženama, svakome po jedan okrugao kruh, komad mesa i kolač od suhoga grožđa."},{"v":4,"t":"Onda je postavio pred Jahvinim Kovčegom službenike među levitima da uznose, slave i hvale Jahvu, Boga Izraelova, i to:"},{"v":5,"t":"poglavara Asafa, a drugoga za njim Zahariju, zatim Jeiela, Šemiramota, Jehiela, Matitju, Eliaba, Benaju, Obed Edoma i Jeiela s harfama i citrama; Asaf je udarao u cimbale."},{"v":6,"t":"Svećenici Benaja i Jahaziel bili su bez prijekida s trubama pred Kovčegom saveza Jahvina."},{"v":7,"t":"Toga dana povjeri David prvi put Asafu i njegovoj braći da slave Jahvu ovom pohvalnicom:"},{"v":8,"t":"“Hvalite Jahvu, prizivajte mu ime; navješćujte među narodima djela njegova!"},{"v":9,"t":"Pjevajte mu, svirajte mu, propovijedajte sva njegova čudesa!"},{"v":10,"t":"Dičite se svetim imenom njegovim, neka se raduje srce onih što traže Jahvu!"},{"v":11,"t":"Tražite Jahvu i njegovu snagu, tražite svagda njegovo lice!"},{"v":12,"t":"Sjetite se čudesa koja učini, njegovih čuda i sudova usta njegovih."},{"v":13,"t":"Izraelov rod njegov je sluga, sinovi Jakovljevi njegovi izabranici."},{"v":14,"t":"On je Jahve, Bog naš; po svoj su zemlji njegovi sudovi!"},{"v":15,"t":"Sjećajte se uvijek njegova Saveza, Riječi koju objavi tisući naraštaja;"},{"v":16,"t":"Saveza koji sklopi s Abrahamom i njegove zakletve Izaku."},{"v":17,"t":"Ustanovi je kao zakon Jakovu, Izraelu vječni Savez."},{"v":18,"t":"Govoreći 'Tebi ću dati kanaansku zemlju kao dio u baštinu vašu,"},{"v":19,"t":"kad vas još bješe malo na broju, vrlo malo, i kad bjeste pridošlice u njoj.'"},{"v":20,"t":"Išli su od naroda do naroda, iz jednoga kraljevstva k drugom narodu."},{"v":21,"t":"Ne dopusti nikom da ih tlači, kažnjavaše zbog njih kraljeve:"},{"v":22,"t":"'Ne dirajte u moje pomazanike, ne činite zla mojim prorocima!'"},{"v":23,"t":"Pjevaj Jahvi, sva zemljo, Navješćujte iz dana u dan spasenje njegovo!"},{"v":24,"t":"Kazujte poganima njegovu slavu, svim narodima čudesa njegova."},{"v":25,"t":"Velik je Jahve, hvale predostojan, strašniji od svih bogova."},{"v":26,"t":"Ništavni su svi bozi naroda. Jahve stvori nebesa."},{"v":27,"t":"Slava je i veličanstvo pred njim, sila i radost u Svetištu njegovu."},{"v":28,"t":"Dajte Jahvi, narodna plemena, dajte Jahvi slavu i silu!"},{"v":29,"t":"Dajte Jahvi slavu imena njegova, nosite prinose i dolazite pred njegovo lice! Poklonite se Jahvi u sjaju svetosti njegove!"},{"v":30,"t":"Strepi pred njim, zemljo sva! Učvrstio je svemir da se ne poljulja."},{"v":31,"t":"Neka se vesele nebesa i neka klikće zemlja; neka se govori među poganima: 'Jahve kraljuje!'"},{"v":32,"t":"Neka huči more i što je u njemu; nek' se raduje polje i što je na njemu!"},{"v":33,"t":"Neka klikće šumsko drveće pred Jahvom, jer dolazi da sudi zemlji."},{"v":34,"t":"Slavite Jahvu jer je dobar, jer je vječna ljubav njegova."},{"v":35,"t":"I recite: 'Spasi nas, o Bože, Spasitelju naš, i saberi nas i izbavi nas od bezbožnih naroda, da slavimo tvoje sveto ime, da se ponosimo tvojom slavom."},{"v":36,"t":"Blagoslovljen Jahve, Bog Izraelov, od vijeka do vijeka!' Sav narod neka kaže: 'Amen! Aleluja!'”"},{"v":37,"t":"I ondje pred Kovčegom saveza Jahvina ostaviše Asafa i njegovu braću da služe pred Kovčegom bez prestanka, koliko treba iz dana u dan;"},{"v":38,"t":"i Obed-Edoma s njegovom braćom, njih šezdeset i osam, i Obed-Edoma, Jedutunova sina, i Hosu, da budu vratari;"},{"v":39,"t":"a svećenika Sadoka s njegovom braćom svećenicima pred Jahvinim Prebivalištem na uzvišici u Gibeonu"},{"v":40,"t":"da prinose paljenice Jahvi na žrtveniku za paljenice bez prestanka, jutrom i večerom, i da vrše sve što je napisano u Zakonu koji je Jahve odredio Izraelu;"},{"v":41,"t":"s njima Hemana i Jedutuna i ostale izabrane, koji su bili poimence spomenuti, da slave Jahvu, “jer je vječna njegova ljubav”;"},{"v":42,"t":"i to Hemana i Jedutuna da trube u trube i udaraju u cimbale i druga glazbala Bogu na čast; a Jedutunove sinove da budu vratari."},{"v":43,"t":"Tada se razišao sav narod, svatko svojoj kući; a David se vratio da blagoslovi svoj dvor."}]},"17":{"hr":[{"v":1,"t":"Kad se David nastanio u dvoru, rekao je proroku Natanu: “Pogledaj! Ja, evo, stojim u dvoru od cedrovine, a Kovčeg saveza Jahvina pod zavjesama!”"},{"v":2,"t":"Natan odgovori Davidu: “Što ti je god na srcu, čini, jer je Bog s tobom.”"},{"v":3,"t":"Ali još iste noći dođe Natanu ova Božja riječ:"},{"v":4,"t":"“Idi i reci mome sluzi Davidu: 'Ovako govori Jahve: Ti mi nećeš sagraditi kuće da prebivam u njoj."},{"v":5,"t":"Nisam nikad prebivao u kući otkako sam izveo Izraela iz Egipta pa do današnjega dana, nego sam išao od šatora do šatora i od prebivališta do prebivališta."},{"v":6,"t":"Dok sam hodio sa svim Izraelom, jesam li ijednu riječ rekao nekom od Izraelovih sudaca, kojima sam zapovjedio da budu pastiri mojem narodu, i kazao: Zašto mi ne sagradite kuću od cedrovine?'"},{"v":7,"t":"Zato sad ovo reci mome sluzi Davidu: 'Ovako govori Jahve nad vojskama: Ja sam te doveo s pašnjaka, od ovaca i koza, da budeš knez nad mojim izraelskim narodom."},{"v":8,"t":"Bio sam s tobom kuda si god išao, iskorijenio sam sve tvoje neprijatelje pred tobom. Ja ću ti pribaviti veliko ime, kao što je velikaško ime na zemlji."},{"v":9,"t":"Odredit ću prebivalište svome izraelskom narodu i posadit ću ga da živi na svojem mjestu i da ne luta više naokolo niti da ga zlikovci muče kao prije,"},{"v":10,"t":"onda kad sam odredio suce nad svojim izraelskim narodom. Pokorit ću sve tvoje neprijatelje i učinit ću te velikim. Jahve će ti podići dom."},{"v":11,"t":"Jer kad se ispune tvoji životni dani i dođe vrijeme da počineš kod otaca, podići ću tvoga potomka nakon tebe, koji će biti između tvojih sinova, i utvrdit ću njegovo kraljevstvo."},{"v":12,"t":"On će mi sagraditi dom, a ja ću utvrditi njegovo prijestolje zauvijek."},{"v":13,"t":"Ja ću njemu biti otac, a on će meni biti sin: svoje naklonosti neću odvratiti od njega, kao što sam je odvratio od tvoga prethodnika."},{"v":14,"t":"Utvrdit ću ga u svojem domu i u svom kraljevstvu zauvijek, i prijestolje će mu čvrsto stajati zasvagda.'”"},{"v":15,"t":"Natan prenese Davidu sve te riječi i cijelo viđenje."},{"v":16,"t":"Tada kralj David dođe i stade pred Jahvu i reče: “Tko sam ja, o Bože Jahve, i što je moj dom te si me doveo dovde?"},{"v":17,"t":"Pa i to je bilo premalo u tvojim očima, o Bože, nego si dao obećanja domu svoga sluge i za daleku budućnost i pogledao si na me kako se gleda na ugledna čovjeka, o Bože Jahve!"},{"v":18,"t":"Pa što da ti još David govori o slavi tvoga sluge; tÓa ti poznaješ svoga slugu!"},{"v":19,"t":"Jahve, radi svoga sluge i po svome srcu učinio si sve ovo veliko djelo, obznanivši ove veličajnosti."},{"v":20,"t":"Jahve, nema takvoga kakav si ti, niti ima Boga osim tebe, po svemu što smo ušima svojim čuli."},{"v":21,"t":"Postoji li ijedan narod na zemlji kao tvoj izraelski narod, radi kojega je Bog išao da ga izbavi sebi za narod, da tako stečeš sebi ime velikim i strašnim čudesima, izgoneći krivobožačka plemena pred svojim narodom koji si otkupio iz Egipta?"},{"v":22,"t":"Tako si učinio svoj izraelski narod svojim narodom zauvijek, a ti si mu, Jahve, postao Bogom."},{"v":23,"t":"Zato sada, Jahve, neka bude čvrsta dovijeka riječ koju si dao svome sluzi i njegovu domu i učini kako si obrekao."},{"v":24,"t":"Neka bude čvrsta, da se veliča tvoje ime zauvijek i da se govori: Jahve nad vojskama, Izraelov Bog, jest Bog nad Izraelom, a dom tvoga sluge Davida neka stoji čvrsto pred tobom."},{"v":25,"t":"Jer si ti, moj Bože, javio uhu svoga sluge da ćeš mu podići dom, zato je tvoj sluga smogao hrabrosti da se pomoli pred tobom."},{"v":26,"t":"Uistinu, Jahve, ti si Bog i ti si ovo lijepo obećanje dao svome sluzi."},{"v":27,"t":"Zato se sada udostoj blagosloviti dom svoga sluge da ostane dovijeka pred tobom, jer kad ti, Jahve, blagosloviš, bit će blagoslovljen zasvagda.”"}]},"18":{"hr":[{"v":1,"t":"Poslije toga David porazi Filistejce i pokori ih te ote Gat s njegovim selima iz filistejskih ruku."},{"v":2,"t":"Porazio je i Moapce i oni postadoše Davidovi podanici koji su mu donosili danak."},{"v":3,"t":"David je porazio i Hadadezera, sopskoga kralja u Hamatu, kad je izišao da utvrdi svoju vlast do rijeke Eufrata."},{"v":4,"t":"David zarobi od njega tisuću bojnih kola, sedam tisuća konjanika i dvadeset tisuća pješaka; ispresijecao je petne žile svim konjima od bojnih kola, ostavio ih je samo stotinu."},{"v":5,"t":"Damaščanski su Aramejci bili došli u pomoć Hadadezeru, sopskome kralju, ali je David pobio među Aramejcima dvadeset i dvije tisuće ljudi."},{"v":6,"t":"Postavio je namjesnike u Damaščanskom Aramu. Tako Aramejci postadoše Davidovi podanici i moradoše mu plaćati danak. Jahve je davao pobjedu Davidu kuda je god išao."},{"v":7,"t":"David zaplijeni zlatne štitove što ih imahu Hadadezerove sluge i donese ih u Jeruzalem."},{"v":8,"t":"I iz Hadadezerovih gradova Tibhata i Kuna odnio je silni tuč od kojega je Salomon načinio mjedeno more, stupove i tučano posuđe."},{"v":9,"t":"Kad je čuo hamatski kralj Tou da je David porazio svu vojsku Hadadezera, sopskoga kralja,"},{"v":10,"t":"posla svoga sina Hadorama kralju Davidu da ga pozdravi i da mu čestita što je vojevao protiv Hadadezera i porazio ga, jer je Tou bio u ratu s Hadadezerom; i da mu odnese svakojakih zlatnih, srebrnih i tučanih predmeta."},{"v":11,"t":"I njih je kralj David posvetio Jahvi sa srebrom i zlatom što ga bijaše uzeo od svih naroda, od Edomaca, Moabaca, Amonaca, Filistejaca i Amalečana."},{"v":12,"t":"Sarvijin sin Abišaj pobio je osamnaest tisuća Edomaca u Slanoj dolini."},{"v":13,"t":"David je postavio namjesnike po Edomu. Tako su svi Edomci postali Davidove sluge. I kuda je god David išao, Jahve mu davaše pobjedu."},{"v":14,"t":"David kraljevaše nad svim Izraelom čineći pravo i pravicu svemu svome narodu."},{"v":15,"t":"Sarvijin je sin Joab bio zapovjednik vojske; Ahiludov sin Jošafat bijaše tajni savjetnik."},{"v":16,"t":"Ahitubov sin Sadok i Ahimelekov sin Ebjatar bili su svećenici, Šavša pisar."},{"v":17,"t":"Jojadin sin Benaja bio je nad Kerećanima i Pelećanima, a Davidovi su sinovi bili prvi do kralja."}]},"19":{"hr":[{"v":1,"t":"Poslije toga umrije Nahaš, kralj Amonaca, i zakralji mu se sin na njegovo mjesto."},{"v":2,"t":"David reče u sebi: “Iskazat ću ljubav Nahaševu sinu Hanunu jer je i njegov otac iskazao milost meni.” David uputi poslanike da mu izraze sućut zbog smrti njegova oca. Kad su Davidove sluge došle u zemlju Amonaca k Hanunu da mu izraze sućut,"},{"v":3,"t":"rekoše knezovi Amonaca Hanunu: “Zar misliš da je David poslao ljude da ti izraze sućut zato što bi htio iskazati čast tvome ocu? Nisu li zato došle njegove sluge k tebi da razvide, istraže i uhode zemlju?”"},{"v":4,"t":"Tada Hanun pograbi Davidove sluge i obrija ih, podreza im haljine dopola, do zadnjice, i posla ih natrag!"},{"v":5,"t":"Kad su to javili Davidu, posla on čovjeka pred njih, jer su bili vrlo osramoćeni, i poruči im: “Ostanite u Jerihonu dok vam ne naraste brada pa se onda vratite.”"},{"v":6,"t":"Kad su Amonovi sinovi vidjeli da su se omrazili s Davidom, poslao je Hanun s Amonovim sinovima tisuću srebrnih talenata da za plaću najme bojnih kola i konjanika iz Aram Naharajima, iz Aram Maake i iz Soba."},{"v":7,"t":"Najmili su za plaću trideset i dvije tisuće bojnih kola, i kralja Maake s njegovim narodom te su oni došli i utaborili se pred Medebom. Amonovi su se sinovi skupili iz svojih gradova i došli u boj."},{"v":8,"t":"Kad je to čuo David, poslao je Joaba sa svom svojom junačkom vojskom."},{"v":9,"t":"Amonovi sinovi iziđoše i svrstaše se u bojni red pred gradskim vratima; a kraljevi koji su došli stajali su zasebno na polju."},{"v":10,"t":"Vidjevši postavljene bojne redove prema sebi, sprijeda i straga, Joab probra najvrsnije među Izraelcima i svrsta ih prema Aramejcima."},{"v":11,"t":"Ostalu vojsku predade bratu Abišaju da je svrsta prema Amoncima."},{"v":12,"t":"I reče mu: “Ako Aramejci budu jači od mene, onda ti meni priskoči u pomoć; ako li Amonci budu jači od tebe, ja ću tebi pohrliti u pomoć."},{"v":13,"t":"Budi hrabar i junački se držimo radi naroda i radi gradova svoga Boga; a Jahve neka učini što je dobro u njegovim očima.”"},{"v":14,"t":"Tada se Joab i vojska koja je bila s njim počeše primicati da udare na Aramejce, ali oni pobjegoše pred njima."},{"v":15,"t":"Kad su Amonci vidjeli da su Aramejci pobjegli, umakoše i oni ispred njegova brata Abišaja i povukoše se u grad. Tada se Joab vrati u Jeruzalem."},{"v":16,"t":"A Aramejci, vidjevši gdje su ih potukli Izraelci, uputili su poslanike i doveli Aramejce što su s onu stranu Rijeke, na čelu sa Šofakom, vojvodom Hadadezerove vojske."},{"v":17,"t":"Pošto su to javili Davidu, on skupi sve Izraelce i, prešavši preko Jordana, primače se Aramejcima i svrsta se prema njima; kad se David svrstao prema Aramejcima u bojni red, oni zametnuše s njime boj."},{"v":18,"t":"Ali Aramejci udariše u bijeg ispred Izraelaca i David im pobi sedam tisuća konja od bojnih kola i četrdeset tisuća pješaka; pogubio je i vojvodu Šofaka."},{"v":19,"t":"Kad Hadadezerove sluge vidješe da ih je razbio Izrael, sklopiše mir s Davidom i počeše mu služiti. A Aramejci se više nisu usuđivali pomagati Amoncima."}]},"20":{"hr":[{"v":1,"t":"Slijedeće godine, u doba kad kraljevi izlaze u rat, izvede Joab vojsku i poče pustošiti zemlju amonsku. Došavši, opsjeo je Rabu; David bijaše ostao u Jeruzalemu. Joab je osvojio Rabu i razorio je."},{"v":2,"t":"Tada je David uzeo njihovu kralju s glave krunu i vidio da je teška jedan zlatni talenat, a na njoj je bilo drago kamenje. Stavili su je na glavu Davidu, koji je iz grada odnio vrlo velik plijen."},{"v":3,"t":"Narod koji bijaše u gradu izvede van i stavi ga da radi pilama, gvozdenim pijucima i sjekirama. Tako je David učinio svim gradovima Amonovih sinova. Potom se vratio sa svim narodom u Jeruzalem."},{"v":4,"t":"Poslije toga opet izbi rat s Filistejcima u Gezeru; tada je Hušanin Sibkaj pogubio Sipaja, koji je bio od Refaimovih potomaka; i bili su pokoreni."},{"v":5,"t":"Uz to je nastao i rat s Filistejcima, u kojem je Jairov sin Elhanan pogubio Lahmija, brata Golijata Gitejca, koji je imao kopljaču kao tkalačko vratilo."},{"v":6,"t":"Potom opet izbi rat u Gatu, gdje je bio neki čovjek visoka rasta: imaše taj na svakoj ruci i nozi po šest prstiju, dakle dvadeset i četiri; i on bijaše Rafin potomak."},{"v":7,"t":"Kad je počeo ružiti Izraela, ubi ga Jonatan, sin Davidova brata Šimeja."},{"v":8,"t":"To su bili Rafini potomci u Gatu koji su izginuli od Davidove ruke i od ruke njegovih slugu."}]},"21":{"hr":[{"v":1,"t":"Tada Satan ustade na Izraela i potače Davida da izbroji Izraelce."},{"v":2,"t":"Kralj reče Joabu i narodnim knezovima: “Idite, izbrojte Izraelce od Beer Šebe pa do Dana, onda se vratite i kažite mi koliko ih je na broju.”"},{"v":3,"t":"Joab reče: “Neka Jahve dade svome narodu još sto puta ovoliko koliko ga je sada! Nisu li, moj gospodaru kralju, svi oni sluge mome gospodaru? Zašto traži to moj gospodar? Zašto da bude na krivicu Izraelu?”"},{"v":4,"t":"Ali kraljeva riječ bijaše jača od Joabove. Tako je Joab otišao i počeo obilaziti sav Izrael, a onda se, najposlije, vrati u Jeruzalem."},{"v":5,"t":"Joab dade Davidu popis naroda; Izraelaca bijaše milijun i sto tisuća ljudi vičnih maču, a Judejaca četiri stotine i sedamdeset tisuća vičnih maču."},{"v":6,"t":"Ali nije pobrojio među njima ni Levijeva ni Benjaminova plemena, jer je Joabu bila odvratna kraljeva zapovijed."},{"v":7,"t":"Bilo je to mrsko i u Božjim očima, pa Bog udari Izraela."},{"v":8,"t":"David reče Bogu: “Veoma sam sagriješio što sam to učinio. Ali oprosti krivicu svome sluzi jer sam vrlo ludo radio!”"},{"v":9,"t":"Jahve reče Davidovu vidiocu Gadu:"},{"v":10,"t":"“Idi i kaži Davidu: 'Ovako veli Jahve: Troje stavljam preda te; izaberi sebi jedno od toga da ti učinim!'”"},{"v":11,"t":"Došavši k Davidu, Gad mu reče: “Ovako veli Jahve: 'Biraj sebi"},{"v":12,"t":"ili glad za tri godine, ili da tri mjeseca bježiš pred neprijateljima i mač tvojih neprijatelja da te stiže, ili da tri dana Jahvin mač i kuga bude na zemlji i Jahvin anđeo da ubija po svim izraelskim krajevima.' Sada promisli i gledaj što da odgovorim onome koji me poslao!”"},{"v":13,"t":"David reče Gadu: “Na velikoj sam muci! Ah, neka padnem u Jahvine ruke, jer je veliko njegovo milosrđe, a u ljudske ruke da ne zapadnem!”"},{"v":14,"t":"Tako je Jahve poslao kugu na Izraela te pomrije sedamdeset tisuća Izraelaca."},{"v":15,"t":"Bog je poslao anđela na Jeruzalem da ga istrebljuje; a kad je počeo istrebljivati, pogledao je Jahve i sažalilo mu se zbog zla, pa je rekao anđelu zatorniku: “Dosta je sada, spusti ruku!” Jahvin je anđeo stajao kraj gumna Jebusejca Ornana."},{"v":16,"t":"David, podigavši oči, vidje Jahvina anđela kako stoji između zemlje i neba držeći u ruci isukan mač koji je podigao na Jeruzalem, i on pade ničice sa starješinama obučenim u kostrijet."},{"v":17,"t":"David reče Bogu: “Nisam li ja zapovjedio da se izbroji narod? Ja sam, dakle, onaj koji sam sagriješio i grdno zlo načinio, a što učiniše te ovce? Jahve, Bože moj, neka tvoja ruka dođe na me i na moju obitelj, a ne na taj narod da ga pomori!”"},{"v":18,"t":"Tada Jahvin anđeo reče Gadu da kaže Davidu neka uziđe i neka podigne žrtvenik Jahvi na gumnu Jebusejca Ornana."},{"v":19,"t":"David je otišao po riječi koju mu je Gad rekao u Jahvino ime."},{"v":20,"t":"A Ornan, okrenuvši se, opazi anđela, a njegova se četiri sina sakriše. Ornan je vrhao pšenicu."},{"v":21,"t":"Uto dođe David do Ornana, a on, pogledavši i opazivši Davida, dođe s gumna i pokloni se Davidu licem do zemlje."},{"v":22,"t":"Tada David reče Ornanu: “Daj mi to gumno da sagradim na njemu žrtvenik Jahvi; za potpunu cijenu daj mi ga da bi prestao pomor u narodu!”"},{"v":23,"t":"Ornan odgovori Davidu: “Neka ga uzme i neka čini moj gospodar kralj što je dobro u njegovim očima; evo, dajem ti goveda za paljenice, i mlatilice za drva, i pšenicu za prinosnicu; sve ti to poklanjam.”"},{"v":24,"t":"Kralj David reče Ornanu: “Ne, nego hoću da kupim u tebe i da platim, jer neću da prinosim Jahvi što je tvoje, da prinosim paljenice koje su mi poklonjene.”"},{"v":25,"t":"I David dade Ornanu za ono mjesto šest stotina zlatnih šekela na mjeru."},{"v":26,"t":"Tada sagradi ondje žrtvenik Jahvi i prinese paljenice i pričesnice; a kad je prizvao Jahvu, on ga usliša spustivši oganj s neba na žrtvenik za paljenice."},{"v":27,"t":"Jahve zapovjedi anđelu da vrati mač u korice."},{"v":28,"t":"U ono vrijeme, vidjevši da ga je Jahve uslišio na gumnu Jebusejca Ornana, David poče prinositi žrtve ondje."},{"v":29,"t":"Jahvino prebivalište, koje je napravio Mojsije u pustinji, i žrtvenik za paljenice bio je u to vrijeme na uzvisini u Gibeonu."},{"v":30,"t":"David nije mogao ići k njemu da traži Boga jer ga je bio spopao strah od mača Jahvina anđela."}]},"22":{"hr":[{"v":1,"t":"Zato David reče: “Ovo je Dom Jahve i ovo je žrtvenik za paljenice Izraelu!”"},{"v":2,"t":"David zapovjedi da se skupe stranci koji su bili u izraelskoj zemlji i odredi klesare da propisno klešu kamenje za gradnju Doma Božjeg."},{"v":3,"t":"David je pripravio mnogo željeza za čavle na vratnim krilima i za kvačice; i bez mjere mnogo tuča."},{"v":4,"t":"Mnogo cedrovine, jer su Sidonci i Tirci dovozili mnogo cedrovih drva Davidu."},{"v":5,"t":"Jer David mišljaše: “Moj je sin Salomon mlad i nježan, a Dom koji treba graditi Jahvi mora biti veličanstven, na slavu i čast po svim zemljama. Hajde da mu sve pripravim.” I David je pripravio mnogo toga prije svoje smrti."},{"v":6,"t":"Potom dozva sina Salomona i zapovjedi mu da sagradi Dom Jahvi, Bogu Izraelovu."},{"v":7,"t":"Još David reče Salomonu: “Sine! Bio sam nakanio u srcu da sagradim Dom imenu Jahve, svoga Boga."},{"v":8,"t":"Ali mi je došla Jahvina riječ: 'Mnogo si krvi prolio i velike si ratove vodio; nećeš ti graditi Doma mome imenu jer si mnogo krvi prolio na zemlju preda mnom."},{"v":9,"t":"Gle, rodit će ti se sin; on će biti miroljubac i dat ću mu mir od svih njegovih neprijatelja odasvud unaokolo; ime će mu biti Salomon. Mir i pokoj dat ću Izraelu za njegova vremena."},{"v":10,"t":"On će sagraditi Dom mome imenu, on će mi biti sin, a ja ću njemu biti otac i utvrdit ću njegovo kraljevsko prijestolje nad Izraelom zauvijek.'"},{"v":11,"t":"Sada, moj sine, neka bude Jahve s tobom da izvršiš i sagradiš Dom Jahve, svoga Boga, kao što je rekao za te."},{"v":12,"t":"Samo neka ti Jahve poda razum i mudrost kad te postavi nad Izraelom zato da se držiš Zakona Jahve, svoga Boga!"},{"v":13,"t":"Bit ćeš sretan budeš li brižno vršio uredbe i zakone koje je Jahve preko Mojsija dao Izraelu. Budi junak i hrabar, ne boj se i ne plaši se!"},{"v":14,"t":"Ja sam, evo, svojim trudom pripravio za Dom Jahvin sto tisuća zlatnih talenata i milijun srebrnih talenata, a tuča i željeza bez mjere, jer ga je tako mnogo. Pripravio sam i drva i kamenja, a i ti dodaj nešto k tomu."},{"v":15,"t":"Imaš mnogo valjanih radnika, klesara, zidara, tesara i svakovrsnih vještaka u svakom umijeću;"},{"v":16,"t":"zlatu, srebru, tuču i željezu nema mjere; idi, dakle, i gradi, i neka Jahve bude s tobom!”"},{"v":17,"t":"Tada David zapovjedi svim izraelskim knezovima da pomažu njegovu sinu Salomonu:"},{"v":18,"t":"“Nije li s vama Jahve, Bog vaš, koji vam je dao mir odasvud unaokolo jer je predao u moje ruke stanovnike ove zemlje i zemlja je pokorena pred Jahvom i pred njegovim narodom."},{"v":19,"t":"Sada, dakle, pregnite svojim srcem i svojom dušom da tražite Jahvu, svoga Boga; idite i gradite Svetište Bogu Jahvi, unesite Kovčeg saveza Jahvina i Božje sveto posuđe u Dom koji će se sagraditi Jahvinu imenu!”"}]},"23":{"hr":[{"v":1,"t":"Ostarjevši i nauživši se dana, postavi David svoga sina Salomona kraljem nad Izraelom."},{"v":2,"t":"Potom skupi sve izraelske knezove, svećenike i levite."},{"v":3,"t":"On izbroji levite od trideset godina naviše, i bilo ih je po muškim glavama trideset i osam tisuća."},{"v":4,"t":"Između njih bilo je dvadeset i četiri tisuće onih koji su upravljali poslom oko Jahvina Doma, a šest tisuća nadzornika i sudaca,"},{"v":5,"t":"četiri tisuće vratara i četiri tisuće onih koji su hvalili Jahvu uz glazbala što ih je napravio za hvalu."},{"v":6,"t":"David ih razdijeli na redove po Levijevim sinovima: Geršonu, Kehatu i Merariju."},{"v":7,"t":"Od Geršonova su koljena bili: Ladan i Šimej."},{"v":8,"t":"Ladanovi sinovi: poglavari Jehiel, Zetam i Joel, njih trojica."},{"v":9,"t":"Šimejevi sinovi: Šelomit, Haziel i Haram, njih trojica; to su poglavari Ladanovih obitelji."},{"v":10,"t":"Šimejevi sinovi: Jahat, Zina, Jeuš i Berija. Ta su četvorica Šimejevi sinovi."},{"v":11,"t":"Jahat je bio poglavar, a drugi Ziza; a Jeuš i Berija nisu imali mnogo djece, zato su se brojili u jednu obitelj, u jedan razred."},{"v":12,"t":"Kehatovi sinovi: Amram, Jishar, Hebron i Uziel, četvorica."},{"v":13,"t":"Amramovi sinovi: Aron i Mojsije. Aron je bio određen da posvećuje Svetinju nad svetinjama; on i njegovi sinovi dovijeka da kade pred Jahvom, da mu služe i da blagoslivljaju u njegovo ime dovijeka."},{"v":14,"t":"Mojsije je bio Božji čovjek. Njegovi se sinovi broje u Levijevo pleme."},{"v":15,"t":"Mojsijevi su sinovi Geršom i Eliezer."},{"v":16,"t":"Geršomovi sinovi: poglavar Šebuel."},{"v":17,"t":"Eliezerovi su sinovi bili: poglavar Rehabja. Eliezer nije imao drugih sinova, nego su se Rehabjini sinovi vrlo namnožili."},{"v":18,"t":"Jisharovi sinovi: poglavar Šelomit."},{"v":19,"t":"Hebronovi sinovi: poglavar Jerija, drugi Amarja, treći Jahaziel, četvrti Jekamam."},{"v":20,"t":"Uzielovi sinovi: poglavar Mika, drugi Ješija."},{"v":21,"t":"Merarijevi sinovi: Mahli i Muši. Mahlijevi sinovi: Eleazar i Kiš."},{"v":22,"t":"Eleazar je umro nemajući sinova, nego samo kćeri, koje su sebi uzeli za žene njihovi rođaci, Kiševi sinovi."},{"v":23,"t":"Mušijevi sinovi: Mahli, Eder i Jerimot, trojica."},{"v":24,"t":"To su bili Levijevi sinovi po obiteljima, poglavari porodica, koji su bili popisani poimence; oni su radili posao za službu Jahvina Doma u dobi od dvadeset godina naviše."},{"v":25,"t":"David je rekao: “Jahve, Izraelov Bog, dao je mir svojem narodu i živjet će u Jeruzalemu zauvijek."},{"v":26,"t":"Zato ni leviti neće više nositi Prebivališta ni svakovrsnog pribora za njegovu službu.”"},{"v":27,"t":"Po posljednjim Davidovim riječima, bili su izbrojeni Levijevi sinovi od dvadeset godina naviše."},{"v":28,"t":"Bili su određeni da budu kraj Aronovih sinova u službi u Jahvinu Domu, u predvorjima i u dvoranama, da čiste sve svete stvari, da rade u službi oko Jahvina Doma,"},{"v":29,"t":"oko prinesenih hljebova, oko sitnog brašna za prinos, oko beskvasnih kolača pripravljenih na tavi i u ulju zamiješenih i oko mjera za sadržaj i dužinu;"},{"v":30,"t":"da pristupaju svakoga jutra, da slave i hvale Jahvu; tako i večerom."},{"v":31,"t":"A kad se god prinose paljenice Jahvi, subotom, za mlađaka i na blagdane, da dolaze prema svom broju, po svom redu, svagdje pred Jahvu."},{"v":32,"t":"I da vrše što treba vršiti u Šatoru sastanka, službu u Svetištu i službu za svoju braću, Aronove sinove, u službi oko Jahvina Doma."}]},"24":{"hr":[{"v":1,"t":"Aronovi su sinovi imali svoje redove. Sinovi Aronovi bili su: Nadab, Abihu, Eleazar i Itamar."},{"v":2,"t":"Ali su Nadab i Abihu umrli prije oca i nisu imali djece; zato su svećeničku službu vršili Eleazar i Itamar."},{"v":3,"t":"David je razdijelio na redove njih i Sadoka, od Eleazarovih sinova, i Ahimeleka, od Itamarovih sinova, po njihovu redu u njihovoj službi."},{"v":4,"t":"Ali se u Eleazarovih sinova našlo više muških poglavara nego u Itamarovih sinova, pa kad ih podijeliše, od Eleazarovih je sinova bilo šesnaest porodičnih poglavara, a od Itamarovih sinova samo osam porodičnih poglavara."},{"v":5,"t":"Zato su ih razdijelili ždrebovima, jedne i druge, jer su posvećeni knezovi i Božji knezovi bili i od Eleazarovih sinova i od Itamarovih sinova."},{"v":6,"t":"Popisao ih je Netanelov sin Šemaja, pisar od Levijeva plemena, pred kraljem, knezovima, svećenikom Sadokom, Ebjatarovim sinom Ahimelekom, pred poglavarima porodica među svećenicima i levitima, uzevši po jednu porodicu za Eleazara, a po jednu opet za Itamara."},{"v":7,"t":"Prvi je ždrijeb pao na Jojariba, drugi na Jedaju,"},{"v":8,"t":"treći na Harima, četvrti na Seorima,"},{"v":9,"t":"peti na Malkiju, šesti na Mijamina,"},{"v":10,"t":"sedmi na Hakosa, osmi na Abiju,"},{"v":11,"t":"deveti na Ješuu, deseti na Šekaniju,"},{"v":12,"t":"jedanaesti na Elijašiba, dvanaesti na Jakima,"},{"v":13,"t":"trinaesti na Hupu, četrnaesti na Ješebaba,"},{"v":14,"t":"petnaesti na Bilgu, šesnaesti na Imera,"},{"v":15,"t":"sedamnaesti na Hezira, osamnaesti na Hapisesa,"},{"v":16,"t":"devetnaesti na Petahju, dvadeseti na Ezekiela,"},{"v":17,"t":"dvadeset i prvi na Jakina, dvadeset i drugi na Gamula,"},{"v":18,"t":"dvadeset i treći na Delaju, dvadeset i četvrti na Maazju."},{"v":19,"t":"To je njihov red u službi kojim treba da idu u Jahvin Dom, po svom pravilu, primljenu od oca im Arona, kako mu je zapovjedio Jahve, Bog Izraelov."},{"v":20,"t":"Od ostalih Levijevih sinova bio je od Amramovih sinova Šubael; od Šubaelovih sinova Jehdeja;"},{"v":21,"t":"od Rehabje, od Rehabjinih sinova poglavar Jišija;"},{"v":22,"t":"od Jisharovaca Šelomot; od Šelomotovih sinova Jahat."},{"v":23,"t":"Od Jerijinih sinova: drugi Amarja, treći Jahaziel, četvrti Jekaman."},{"v":24,"t":"Od sinova Uzielovih Mika; od Mikinih sinova Šamir;"},{"v":25,"t":"Mikin brat Jišija; od Jišijinih sinova Zaharija;"},{"v":26,"t":"Merarijevi sinovi: Mahli i Muši; sinovi Jaazije, njegova sina."},{"v":27,"t":"Merarijevi sinovi po Jaaziji, njegovu sinu: Šoham, Zakur i Ibri;"},{"v":28,"t":"po Mahliju Eleazar, koji nije imao djece;"},{"v":29,"t":"po Kišu, Kišovi sinovi, Jerahmeel."},{"v":30,"t":"Mušijevi sinovi: Mahli, Eder i Jerimot. To su bili levitski sinovi po svojim porodicama."},{"v":31,"t":"I oni su bacali ždrebove kao njihovi rođaci, Aronovi sinovi, pred kraljem Davidom, Sadokom, Ahimelekom i porodičnim poglavarima među svećenicima i levitima, i to jednako glavar obitelji kao i njegov najmlađi brat."}]},"25":{"hr":[{"v":1,"t":"David je s vojničkim zapovjednicima izabrao za službu Asafove, Hemanove i Jedutunove sinove koji će zanosno pjevati hvalu uz citre, harfe i cimbale; između njih su bili izbrojeni ljudi za posao u svojoj službi:"},{"v":2,"t":"od Asafovih sinova: Zakur, Josip, Netanija i Asarela; Asafovi sinovi pod upravom Asafa, koji je zanosno pjevao hvalu po kraljevoj uredbi."},{"v":3,"t":"Od Jedutuna: Jedutunovih šest sinova: Gedalija, Sori, Ješaja, Šimej, Hašabja i Matitja pod upravom svog oca Jedutuna koji je zanosno pjevao hvalu uz citru slaveći i hvaleći Jahvu."},{"v":4,"t":"Od Hemana: Hemanovi sinovi: Bukija, Matanija, Uziel, Šebuel, Jerimot, Hananija, Hanani, Eliata, Gidalti, Romamti-Ezer, Jošbekaša, Maloti, Hotir, Mahaziot."},{"v":5,"t":"Svi su oni bili sinovi kraljeva vidioca Hemana koji je objavljivao Božje stvari da uzvisi njegovu moć; a Bog je dao Hemanu četrnaest sinova i tri kćeri."},{"v":6,"t":"Svi su oni pod vodstvom svoga oca Asafa te Jedutuna i Hemana pjevali u Jahvinu Domu uz cimbale, harfe i citre za službu u Božjem Domu, po kraljevoj uredbi."},{"v":7,"t":"Bilo ih je, s njihovom braćom, uvježbanih u pjevanju Jahvinih pjesama, dvjesta osamdeset i osam, sve samih vještaka."},{"v":8,"t":"Bacili su ždrebove za svoju službenu dužnost, najmanji isto kao i najveći, učitelj kao i učenik."},{"v":9,"t":"Prvi je ždrijeb pao na Asafovca Josipa, drugi na Gedaliju s njegovom braćom i sinovima, njih dvanaest,"},{"v":10,"t":"treći na Zakura s njegovim sinovima i braćom, njih dvanaest;"},{"v":11,"t":"četvrti na Jisrija s njegovim sinovima i braćom, njih dvanaest;"},{"v":12,"t":"peti na Netaniju s njegovim sinovima i braćom, njih dvanaest;"},{"v":13,"t":"šesti na Bukiju s njegovim sinovima i braćom, njih dvanaest,"},{"v":14,"t":"sedmi na Isarelu s njegovim sinovima i braćom, njih dvanaest;"},{"v":15,"t":"osmi na Ješaja s njegovim sinovima i braćom, njih dvanaest;"},{"v":16,"t":"deveti na Mataniju s njegovim sinovima i braćom, njih dvanaest;"},{"v":17,"t":"deseti na Šimeja s njegovim sinovima i braćom, njih dvanaest;"},{"v":18,"t":"jedanaesti na Azarela s njegovim sinovima i braćom, njih dvanaest;"},{"v":19,"t":"dvanaesti na Hašabju s njegovim sinovima i braćom, njih dvanaest;"},{"v":20,"t":"trinaesti na Šubaela s njegovim sinovima i braćom, njih dvanaest;"},{"v":21,"t":"četrnaesti na Matitju s njegovim sinovima i braćom, njih dvanaest;"},{"v":22,"t":"petnaesti na Jeremota s njegovim sinovima i braćom, njih dvanaest;"},{"v":23,"t":"šesnaesti na Hananiju s njegovim sinovima i braćom, njih dvanaest;"},{"v":24,"t":"sedamnaesti na Jošbekaša s njegovim sinovima i braćom, njih dvanaest;"},{"v":25,"t":"osamnaesti na Hananija s njegovim sinovima i braćom, njih dvanaest;"},{"v":26,"t":"devetnaesti na Malotija s njegovim sinovima i braćom, njih dvanaest;"},{"v":27,"t":"dvadeseti na Elijatu s njegovim sinovima i braćom, njih dvanaest;"},{"v":28,"t":"dvadeset i prvi na Hotira s njegovim sinovima i braćom, njih dvanaest;"},{"v":29,"t":"dvadeset i drugi na Gidaltija s njegovim sinovima i braćom, njih dvanaest;"},{"v":30,"t":"dvadeset i treći na Mahaziota s njegovim sinovima i braćom, njih dvanaest;"},{"v":31,"t":"dvadeset i četvrti na Romamti-Ezera s njegovim sinovima i braćom, njih dvanaest."}]},"26":{"hr":[{"v":1,"t":"Vratarski su redovi bili: od Korahovaca: Korahov sin Mešelemja između Asafovih sinova;"},{"v":2,"t":"a Mešelemjini sinovi: prvenac Zaharija, drugi Jediael, treći Zebadja, četvrti Jatniel;"},{"v":3,"t":"peti Elam, šesti Johanan, sedmi Elijoenaj."},{"v":4,"t":"Sinovi Obed-Edomovi: prvenac Šemaja, drugi Jozabad, treći Joah, četvrti Sakar, a peti Netanel,"},{"v":5,"t":"šesti Amiel, sedmi Jisakar, osmi Peuletaj, jer ga je blagoslovio Bog,"},{"v":6,"t":"a njegovu su se sinu Šemaji rodili sinovi koji su bili poglavari u porodici jer bijahu hrabri junaci."},{"v":7,"t":"Šemajini su sinovi bili: Otni, Rafael, Obed, Elzabad sa svojom braćom, vrsnim ljudima, Elihu i Semakja."},{"v":8,"t":"Svi su oni bili od Obed-Edomovih sinova, oni i njihovi sinovi i njihova braća, vrsni ljudi, sposobni za službu; bilo ih je šezdeset i dva od Obed-Edoma."},{"v":9,"t":"Mešelemjinih sinova i braće, vrsnih ljudi, bilo je osamnaest."},{"v":10,"t":"Hosini sinovi od Merarijevih sinova: poglavar Šimri, iako nije bio prvenac, njegov ga je otac postavio za poglavara;"},{"v":11,"t":"drugi Hilkija, treći Tebalija, četvrti Zaharija; Hosinih svih sinova i braće bilo je trinaest."},{"v":12,"t":"Ovo su vratarski redovi. Glavari ovih junaka bili su, kao i njihova braća, čuvari u službi Jahvina Doma."},{"v":13,"t":"Bacali su ždrebove, najmanji kao i najveći, po obiteljima za svaka pojedina vrata."},{"v":14,"t":"Ždrijeb na istok pao je Šelemji; njegov sin Zaharija bio je mudar savjetnik. Kad su bacili ždrebove, dopao mu je ždrijeb na sjever,"},{"v":15,"t":"Obed-Edomu na jug; a njegovim sinovima na spremište;"},{"v":16,"t":"Šufimu i Hosi na zapad Šaleketskim vratima, na putu koji vodi k usponu; straža je bila do straže."},{"v":17,"t":"S istoka šest levita, sa sjevera četiri na dan, s juga četiri na dan; a kod spremišta po dva."},{"v":18,"t":"Na hramskoj prigradnji, sa zapada, četiri na usponu, dva kod prigradnje."},{"v":19,"t":"To su vratarski redovi među Korahovim i Merarijevim sinovima."},{"v":20,"t":"Leviti, njihova braća, bili su: Ahija nad blagom Božjega Doma i nad blagom posvećenih stvari."},{"v":21,"t":"Ladanovi sinovi, Geršonovci po Ladanu, poglavari obitelji Ladana Geršonovca, bili su Jehielovci."},{"v":22,"t":"Jehielovci Zetam i brat mu Joel bili su nadstojnici nad blagom Jahvina Doma."},{"v":23,"t":"Od Amramovaca, Jisharovaca, Hebronovaca i Uzielovaca bili su:"},{"v":24,"t":"Šebuel, sin Mojsijeva sina Geršoma, nadstojnik nad blagom."},{"v":25,"t":"Njegova braća po Eliezeru: Rehabja, sin mu, njegov sin Izaija, njegov sin Joram, njegov sin Zikri, njegov sin Šelomit."},{"v":26,"t":"Taj je Šelomit sa svojom braćom bio odgovoran za sve blago od posvećenih stvari koje je posvetio kralj David s porodičnim poglavarima, s tisućnicima, stotnicima i vojnim zapovjednicima."},{"v":27,"t":"Posvetili su dio ratnog plijena da se bolje ojača Jahvin Dom."},{"v":28,"t":"Što je god bio posvetio vidjelac Samuel, Kišev sin Šaul, Nerov sin Abner i Sarvijin sin Joab, sve posvećeno, bilo je pod nadzorom Šelomita i njegove braće."},{"v":29,"t":"Jisharovci Kenanija i njegovi sinovi bili su nad svjetovnim poslovima kao nadzornici i suci u Izraelu."},{"v":30,"t":"Hebronovci Hašabja i njegova braća, tisuću i sedam stotina vrsnih ljudi, upravljali su Izraelom s ovu stranu Jordana na zapadu u svakom Jahvinu poslu i u kraljevskoj službi."},{"v":31,"t":"Poglavar Hebronovaca bio je Jerija. Četrdesete godine Davidova kraljevanja potražili su obiteljska rodoslovlja Hebronovaca i našlo se među njima vrsnih ljudi u Gileadskom Jazeru."},{"v":32,"t":"Njegove braće, vrsnih ljudi, bilo je dvije tisuće i sedam stotina porodičnih poglavara; kralj David postavio ih je nad Rubenovim i Gadovim plemenom i nad polovinom Manašeova plemena za sve Božje poslove i za kraljevske poslove."}]},"27":{"hr":[{"v":1,"t":"Izraelovi sinovi po svome broju. Poglavari porodica, tisućnici, stotnici i nadzornici služili su kralju u svakom poslu. U redovima su dolazili i odlazili od mjeseca do mjeseca, u svim godišnjim mjesecima; svaki je red imao dvadeset i četiri tisuće ljudi."},{"v":2,"t":"Nad prvim je redom, prvoga mjeseca, bio Zabdielov sin Jašobam. U svom je redu imao dvadeset i četiri tisuće ljudi."},{"v":3,"t":"Pripadao je Peresovim sinovima i bio zapovjednik svih vojvoda u vojsci prvoga mjeseca."},{"v":4,"t":"Nad redom drugoga mjeseca bio je Ahošanin Dodaj, a predstojnik u njegovu redu bio je Mikelot. U svom je redu imao dvadeset i četiri tisuće ljudi."},{"v":5,"t":"Vojvoda treće vojske, trećega mjeseca, bio je sin svećenika Jojade, poglavar Benaja. U svom je redu imao dvadeset i četiri tisuće."},{"v":6,"t":"Taj je Benaja bio junak među tridesetoricom i nad tridesetoricom i u njegovu je redu bio sin mu Amizabad."},{"v":7,"t":"Četvrti, četvrtoga mjeseca, bio je Joabov brat Asahel, a za njim sin mu Zebadja. U svom je redu imao dvadeset i četiri tisuće."},{"v":8,"t":"Peti, petoga mjeseca, bio je vojvoda Jizrahanin Šamhut. U svom je redu imao dvadeset i četiri tisuće."},{"v":9,"t":"Šesti, šestoga mjeseca, bio je Ikešov sin Ira, Tekoanac. U svom je redu imao dvadeset i četiri tisuće."},{"v":10,"t":"Sedmi, sedmoga mjeseca, bio je Pelonjanin Heles od Efrajimovih sinova. U svom je redu imao dvadeset i četiri tisuće."},{"v":11,"t":"Osmi, osmoga mjeseca, bio je Hušaćanin Sibkaj, Zarhijevac. U svom je redu imao dvadeset i četiri tisuće."},{"v":12,"t":"Deveti, devetoga mjeseca, bio je Anatoćanin Abiezer, Benjaminovac. U svom je redu imao dvadeset i četiri tisuće."},{"v":13,"t":"Deseti, desetoga mjeseca, bio je Netofaćanin Mahraj, Zarhijevac. U svom je redu imao dvadeset i četiri tisuće."},{"v":14,"t":"Jedanaesti, jedanaestoga mjeseca, bio je Piratonjanin Benaja, Efrajimovac. U svom je redu imao dvadeset i četiri tisuće."},{"v":15,"t":"Dvanaesti, dvanaestoga mjeseca, bio je Netofaćanin Heldaj, Otnielovac. U svom je redu imao dvadeset i četiri tisuće."},{"v":16,"t":"Nad Izraelovim plemenima bili su knezovi: nad Rubenovim Zikrijev sin knez Eliezer; nad Šimunovim Maakin sin Šefatja;"},{"v":17,"t":"nad Levijevim Kemuelov sin Hašabja; nad Aronovim Sadok;"},{"v":18,"t":"nad Judinim Elihu od Davidove braće; nad Jisakarovim Mihaelov sin Omri;"},{"v":19,"t":"nad Zebulunovim Obadjin sin Jišmaja; nad Naftalijevim Azrielov sin Jerimot."},{"v":20,"t":"Nad Efrajimovim sinovima Azazjin sin Hošea; nad polovinom Manašeova plemena Pedajin sin Joel,"},{"v":21,"t":"nad drugom polovinom Manašeova plemena u Gileadu Zaharijin sin Jido; nad Benjaminom Abnerov sin Jaasiel;"},{"v":22,"t":"nad Danom Jerohamov sin Azarel. To su bili knezovi izraelskih plemena."},{"v":23,"t":"Ali David nije dao izbrojiti onih kojima bijaše dvadeset godina i manje, jer Jahve bijaše rekao da će umnožiti Izraelce kao nebeske zvijezde."},{"v":24,"t":"Sarvijin je sin Joab počeo vršiti popis, ali ga nije dovršio. Stoga je Srdžba došla na Izrael i zato taj broj nije bio primljen u brojčani izvještaj Ljetopisa kralja Davida."},{"v":25,"t":"Nadstojnik nad kraljevim blagom bio je Adielov sin Azmavet, a nadstojnik za blago u zemlji, u gradovima, selima i tvrđavama, bio je Uzijin sin Jonatan."},{"v":26,"t":"Nadstojnik nad poljskim radnicima koji su obrađivali zemlju bio je Kelubov sin Ezri."},{"v":27,"t":"Nadstojnik nad vinogradarima Ramaćanin Šimej. Nadstojnik nad vinogradrskim klijetima bio je Šifmejac Zabdi."},{"v":28,"t":"Nadstojnik nad maslinama i dudovima što su po Šefeli bio je Gederac Hanan; nadstojnik nad skladištima ulja Joaš."},{"v":29,"t":"Nadstojnik nad govedima što su pasla u Šaronu bio je Šaronac Šitraj. Nadstojnik nad krupnom stokom u dolinama bio je Edlajev sin Šafat."},{"v":30,"t":"Nadstojnik nad devama Jišmaelac Obil. Nadstojnik nad magaricama Meronoćanin Jehdeja."},{"v":31,"t":"Nadstojnik nad ovcama i kozama Hagrijac Jaziz. Svi su oni bili nadstojnici nad imanjem kralja Davida."},{"v":32,"t":"Savjetnik je bio Davidov stric Jonatan, mudar čovjek; bio je i književnik; a Hakmonijev sin Jehiel bio je s kraljevim sinovima."},{"v":33,"t":"Ahitofel je bio kraljev savjetnik, Arkijac Hušaj kraljev prijatelj."},{"v":34,"t":"Ahitofela su naslijedili Benajin sin Jojada i Ebjatar, kraljev je vojvoda bio Joab."}]},"28":{"hr":[{"v":1,"t":"David sakupi u Jeruzalem sve izraelske knezove, plemenske knezove i poglavare od redova koji su služili kralja, tisućnike, stotnike i nadstojnike nad svim imanjem i blagom kraljevim i blagom njegovih sinova, zajedno s dvoranima i junacima i svim hrabrim vojnicima."},{"v":2,"t":"Ustavši na noge, kralj David reče: “Čujte me, moja braćo i moj narode! Ja sam bio namislio u svom srcu da sagradim dom gdje bi počivao Kovčeg saveza Jahvina i da bude podnožje nogama našega Boga te sam pripravio što treba za gradnju."},{"v":3,"t":"Ali mi je Bog rekao: 'Nećeš ti sagraditi Doma mome imenu jer si ratnik i prolijevao si krv.'"},{"v":4,"t":"Jahve, Izraelov Bog, izabrao je mene od sveg moga roda da budem kralj nad Izraelom zauvijek; jer je Judu izabrao za kneza, a iz Judina doma dom moga oca; između sinova moga oca bilo mu je drago da mene postavi kraljem nad svim Izraelom."},{"v":5,"t":"Tako je između mojih sinova, jer mi je mnogo sinova dao Jahve, izabrao moga sina Salomona da sjedi na prijestolju Jahvina kraljevstva nad Izraelom."},{"v":6,"t":"I rekao mi je: 'Tvoj sin Salomon sagradit će meni Dom i moja predvorja; jer sam njega izabrao sebi za sina i ja ću mu biti otac."},{"v":7,"t":"Utvrdit ću njegovo kraljevstvo zauvijek ako bude postojano vršio moje zapovijedi i moje zakone kao danas.'"},{"v":8,"t":"Sada, dakle, pred očima sveg Izraela, Jahvina zbora, i pred svojim Bogom, koji nas sluša, velim: držite i tražite sve zapovijedi Jahve, svoga Boga, da biste zadržali u posjedu ovu dobru zemlju i ostavili je u baštinu svojim sinovima nakon sebe dovijeka."},{"v":9,"t":"A ti, sine moj Salomone, poznaj Boga, svoga oca, i služi mu čitavim srcem i spremnom dušom, jer Jahve ispituje sva srca i zna sve misli i namjere; ako ga budeš tražio, dat će ti se da ga nađeš; ako li ga ostaviš, odbacit će te zauvijek."},{"v":10,"t":"Uvidi sada da te Jahve izabrao da gradiš Dom za Svetište, budi junak i radi!”"},{"v":11,"t":"Tada David predade sinu Salomonu uzorak trijema, njegovih kuća, riznica, gornjih soba, ćelija i doma Pomirilišta;"},{"v":12,"t":"uzorak svega što bijaše smislio u duhu za predvorja Jahvina Doma, za sve sobe unaokolo, za riznicu Doma Božjega, za riznicu posvećenih stvari,"},{"v":13,"t":"za svećeničke i levitske redove, za svaki posao u službi oko Doma Jahvina:"},{"v":14,"t":"zlato u šipkama, zlato potrebno za sve zlatno posuđe ove ili one službe; srebro u šipkama potrebno za sve srebrno posuđe, za sve posuđe ove ili one službe;"},{"v":15,"t":"šipke za zlatne svijećnjake sa zlatnim svjetiljkama, prema težini svakoga svijećnjaka i njegovih svjetiljaka, i za srebrne svijećnjake prema težini svakoga svijećnjaka i njegovih svjetiljaka i prema namjeni svakog svijećnjaka;"},{"v":16,"t":"zlato u šipkama za stolove na kojima će stajati prineseni hljebovi, za svaki stol; srebro za srebrne stolove,"},{"v":17,"t":"za viljuške i kotliće, za čaše od čista zlata, za zlatne pehare, zlato u šipkama za svaki pehar; za srebrne pehare, srebro u šipkama za svaki pehar,"},{"v":18,"t":"za kadioni žrtvenik žeženoga zlata u šipkama; za uzorak od kola sa zlatnim kerubinima koji će raširenim krilima zaklanjati Jahvin Kovčeg."},{"v":19,"t":"Sve to u skladu s onim što Jahve napisa vlastitom rukom da bi razjasnio cijelo djelo za koje on pribavi uzorak."},{"v":20,"t":"Tada David reče svome sinu Salomonu: “Budi junak, hrabar, i radi! Ne boj se i ne plaši se, jer će Jahve, Bog, moj Bog, biti s tobom! Neće te napustiti niti te ostaviti dok ne svršiš sav posao za službu oko Jahvina Doma."},{"v":21,"t":"Evo svećeničkih i levitskih redova za svaku službu u Božjem Domu; imaš uza se za svaki posao svakovrsnih ljudi, spremnih i vještih svakoj službi, knezovi i sav narod pod tvojim su zapovjedništvom.”"}]},"29":{"hr":[{"v":1,"t":"Kralj David reče svemu zboru: “Bog je izabrao moga sina Salomona, mlado i nježno momče, a ovo je velik posao, jer neće biti za čovjeka dvor nego za Boga Jahvu."},{"v":2,"t":"Pripremio sam, koliko sam mogao, za Dom svoga Boga zlata za zlatne stvari i srebra za srebrne, tuča za tučane, željeza za željezne, drva za drvene; oniksova kamenja i dragulja za ukivanje, dragulja za ukras i šarenih dragulja, svakojakoga dragog kamenja i izobila mramora."},{"v":3,"t":"Iz ljubavi prema Bogu dajem još i svoga zlata i srebra za Dom svoga Boga, osim svega što sam pripravio za sveti Dom."},{"v":4,"t":"Tri tisuće zlatnih talenata ofirskoga zlata i sedam tisuća talenata čistoga srebra da se oblože zidovi prostorija."},{"v":5,"t":"Zlato za zlatne stvari, a srebro za srebrne i za svako djelo umjetničkih ruku. Bi li danas još tko htio dragovoljno što priložiti svojom rukom Jahvi?”"},{"v":6,"t":"Tada su dragovoljno priložili knezovi obitelji i knezovi izraelskih plemena, tisućnici, stotnici i nadstojnici nad kraljevskim poslovima."},{"v":7,"t":"Dali su za službu u Božjem Domu zlata pet tisuća talenata i deset tisuća zlatnih darika, srebra deset tisuća talenata, tuča osamnaest tisuća talenata, željeza sto tisuća talenata."},{"v":8,"t":"U koga se god našlo dragulja, svi su darivali u riznicu Jahvina Doma na ruke Jehiela Geršonovca."},{"v":9,"t":"Narod se veselio što su dragovoljno prilagali, jer su prilagali iskrena srca Jahvi; i kralj David radovao se od srca."},{"v":10,"t":"Potom David blagoslovi Jahvu pred svim zborom. I reče David: “Blagoslovljen da si, Jahve, Bože našeg oca Izraela, od vijeka do vijeka!"},{"v":11,"t":"Tvoja je, Jahve, veličina, sila, slava, sjaj i veličanstvo, jer je tvoje sve što je na nebu i na zemlji; tvoje je, Jahve, kraljevstvo i ti si uzvišen povrh svega, Poglavar svega!"},{"v":12,"t":"Od tebe je bogatstvo i slava, ti vladaš nad svim, u tvojoj je ruci sila i moć, u tvojoj je vlasti da učiniš velikim i jakim sve."},{"v":13,"t":"I slavimo te, Bože naš, i hvalimo tvoje dično ime."},{"v":14,"t":"Tko sam ja i što je moj narod da bismo imali snage ovoliko prinijeti tebi dragovoljno? Od tebe je sve, i iz tvojih ruku primivši, dali smo tebi!"},{"v":15,"t":"Pridošlice smo pred tobom, naseljenici kao svi naši očevi; naši dani na zemlji prolaze kao sjena i nema nade."},{"v":16,"t":"Jahve, Bože naš, sve ovo mnogo blago koje smo pripravili za gradnju Doma tebi, tvome svetom imenu, iz tvoje je ruke i sve je tvoje!"},{"v":17,"t":"Ali znam, o Bože moj, da ti iskušavaš srca i da ljubiš iskrenost; ja sam iskrena srca dragovoljno prinio sve ovo i s radošću sam gledao tvoj narod koji je ovdje kako ti dragovoljno prinosi."},{"v":18,"t":"Jahve, Bože naših otaca Abrahama, Izaka i Jakova, sačuvaj dovijeka u srcu svoga naroda tu misao i namjeru i upravi njegovo srce k sebi!"},{"v":19,"t":"A mome sinu Salomonu daj pošteno srce da bi se držao tvojih zapovijedi, tvojih odredaba i tvojih uredaba, da bi vršio sve i da bi sagradio dvor za koji sam sve spremio!”"},{"v":20,"t":"Tada David reče svemu zboru: “Blagoslovite sada Jahvu, svoga Boga!” I sav je zbor blagoslovio Jahvu, Boga svojih otaca, i, pavši ničice, poklonio se Jahvi i kralju."},{"v":21,"t":"Žrtvovali su Jahvi klanice i prinijeli Jahvi paljenice sutradan: tisuću junaca, tisuću ovnova, tisuću jaganjaca s njihovim ljevanicama, mnogo drugih žrtava za sav Izrael."},{"v":22,"t":"Jeli su i pili pred Jahvom onoga dana vrlo se radujući. Zakraljili su po drugi put Davidova sina Salomona i pomazali ga po Jahvinoj volji za kneza, a Sadoka za svećenika."},{"v":23,"t":"Tako je Salomon sjeo na Jahvino prijestolje da kraljuje namjesto svoga oca Davida. Bio je sretan i slušao ga je sav Izrael."},{"v":24,"t":"Svi su knezovi i junaci i svi sinovi kralja Davida pružili ruku kralju Salomonu i svečano mu obećali pokornost."},{"v":25,"t":"Jahve je vrlo uzvisio Salomona pred očima sveg Izraela i dao njegovu kraljevstvu veličanstvo kakvo nijedan kralj prije njega nije imao u Izraelu."},{"v":26,"t":"Tako je Jišajev sin David kraljevao nad svim Izraelom."},{"v":27,"t":"Nad Izraelom je kraljevao četrdeset godina; u Hebronu je kraljevao sedam godina, u Jeruzalemu je kraljevao trideset i tri godine."},{"v":28,"t":"Umro je u lijepoj starosti, nauživši se života, bogatstva i slave. Na njegovo se mjesto zakraljio sin mu Salomon."},{"v":29,"t":"Djela kralja Davida, od prvog do posljednjeg, zapisana su u povijesti vidioca Samuela, u povijesti proroka Natana i u povijesti vidioca Gada,"},{"v":30,"t":"sa svim njegovim kraljevanjem, njegovim junaštvom i događajima što prijeđoše preko njega i Izraela i svih drugih kraljevstava zemaljskih."}]}},"2CH":{"1":{"hr":[{"v":1,"t":"Salomon, sin Davidov, bio se učvrstio na prijestolju. Jahve, Bog njegov, bijaše s njim i uzvisi ga veoma."},{"v":2,"t":"Salomon se tada obrati svem Izraelu, tisućnicima, satnicima, sucima, svim knezovima izraelskim, glavama obitelji,"},{"v":3,"t":"te se on i s njim sav Zbor popeše na uzvišicu koja bješe u Gibeonu, jer je ondje bio Šator sastanka što ga u pustinji podiže Mojsije, sluga Božji."},{"v":4,"t":"David bijaše prenio Kovčeg Božji iz Kirjat Jearima do mjesta koje je sam pripravio za nj; jer je bio podigao Šator u Jeruzalemu."},{"v":5,"t":"Tučani žrtvenik što ga napravi Besalel, sin Hurova sina Urija, bijaše ondje pred Prebivalištem Jahvinim, kamo dođoše Salomon i zbor da mu se obrate."},{"v":6,"t":"Ondje se Salomon pred Jahvom pope na tučani žrtvenik, koji bješe tik do Šatora sastanka, i prinese na njemu tisuću paljenica."},{"v":7,"t":"Iste se noći Bog ukaza Salomonu i reče mu: “Traži što da ti dadem.”"},{"v":8,"t":"Salomon odgovori: “Veoma si naklon bio mome ocu Davidu i zakraljio si mene na njegovo mjesto."},{"v":9,"t":"Bože Jahve, neka se ispuni sada obećanje što si ga dao mome ocu Davidu, jer si me zakraljio nad narodom kojega ima mnogo kao zemaljske prašine."},{"v":10,"t":"Daj mi sada mudrost i znanje da uzmognem upravljati ovim narodom, jer tko će upravljati tolikim narodom kao što je ovaj tvoj!”"},{"v":11,"t":"Bog reče Salomonu: “Budući da ti je to u srcu, a nisi iskao ni bogatstva, ni blaga, ni slave, ni smrti neprijatelja i jer nisi tražio duga života nego mudrosti i znanja kako bi upravljao mojim narodom nad kojim te zakraljih,"},{"v":12,"t":"dajem ti mudrost i znanje. Ali ti dajem i bogatstva, blaga i slave kakve nije imao nijedan kralj što bješe prije tebe i kakve neće imati ni oni koji dođu poslije tebe.”"},{"v":13,"t":"Salomon s uzvišice u Gibeonu ode u Jeruzalem, podalje od Šatora sastanka, i kraljevaše nad Izraelom."},{"v":14,"t":"Sakupi bojnih kola i konjanika: imao je tisuću četiri stotine kola i dvanaest tisuća konjanika i razmjesti ih po gradovima gdje mu bijahu kola i kod sebe u Jeruzalemu."},{"v":15,"t":"Salomon učini da srebra i zlata bude u Jeruzalemu izobila kao kamenja, a cedrova mnogo kao dudova u Šefeli."},{"v":16,"t":"Konji Salomonovi bili su uvezeni iz Musrija i Koe; kraljevski dvorani kupovahu ih u Koi za srebro."},{"v":17,"t":"Dovozila su se i prodavala jedna bojna kola iz Egipta po šest stotina srebrnih šekela, a konji po sto i pedeset; to bješe isto tako za sve hetitske i aramejske kraljeve koji su ih uvozili preko njih."},{"v":18,"t":"Salomon naumi sagraditi Dom - jedan Imenu Jahvinu, a drugi sebi za kraljevski dvorac."}]},"2":{"hr":[{"v":1,"t":"Odbroji sedamdeset tisuća nosača, osamdeset tisuća kamenolomaca u gori i tri tisuće i šest stotina poslovođa."},{"v":2,"t":"Tada posla ovu poruku Hiramu, tirskomu kralju: “Kao što si mome ocu Davidu slao cedrovine da gradi dvor gdje će živjeti, tako učini i meni."},{"v":3,"t":"Kanim podići Dom Imenu Jahve, svojega Boga, i posvetiti mu ga da se diže pred njim miomirisni kad, da se uvijek postavljaju kruhovi, da se prinose paljenice jutrom i večerom, subotom, na dane mlađaka i na blagdane Jahve, Boga našega; i tako da zauvijek ostane u Izraelu."},{"v":4,"t":"Dom koji gradim bit će velik, jer je naš Bog najveći među svim bozima."},{"v":5,"t":"TÓa tko bi imao dovoljno snage da njemu sazda Dom kad ga ni nebesa, ni nebesa nad nebesima ne mogu obuhvatiti? I tko sam ja da mu zidam Dom, osim zato da mu se kad diže pred lice?"},{"v":6,"t":"Pošalji mi čovjeka vična obradi zlata, srebra, tuča, željeza, grimiza, karmezina i ljubičastog baršuna, i vična umjetnosti rezbarstva: radit će s rukotvorcima kod mene u Judi i u Jeruzalemu, s onima što mi ih ostavi moj otac David."},{"v":7,"t":"Pošalji mi iz Libanona cedrovine, čempresovine i sandalovine, jer znam da tvoje sluge umiju sjeći libanonska stabla. Moje će sluge raditi s tvojima."},{"v":8,"t":"Morat će mi pripraviti mnogo drva, jer će kuća što je mislim graditi biti velika i veličanstvena."},{"v":9,"t":"Drvosječama što će obarati stabla dajem dvadeset tisuća kora pšenice, dvadeset tisuća kora ječma, dvadeset tisuća bata vina i dvadeset tisuća bata ulja za izdržavanje tvojih slugu.”"},{"v":10,"t":"Hiram, tirski kralj, odgovori pismom što ga posla Salomonu: “Zato što voli svoj narod, Jahve te zakraljio nad njim.”"},{"v":11,"t":"Dometnu još i ovo: “Neka je blagoslovljen Jahve, Bog Izraelov, koji je stvorio nebesa i zemlju. On je kralju Davidu dao mudra, pametna i umna sina koji će jedan dom graditi Jahvi, a drugi sebi da iz njega kraljuje."},{"v":12,"t":"Stoga ti šaljem čovjeka mudra, vješta i razumna, Hurama Abija,"},{"v":13,"t":"sina jedne Danovke i oca Tirca. Umije obrađivati zlato, srebro, tuč, željezo, kamen, drvo, grimiz, ljubičasti baršun, bÓez i karmezin, umije rezbariti svakovrsne rezbarije i zamisliti svako djelo koje mu se povjeri. On će raditi s tvojim umjetnicima i umjetnicima moga gospodara Davida, tvoga oca."},{"v":14,"t":"Neka, dakle, sada moj gospodar svojim slugama pošalje pšenice, ječma, ulja i vina kako je obećao."},{"v":15,"t":"A mi ćemo nasjeći stabala s Libanona koliko ti god treba i dovest ćemo ti ih na splavima morem u Jafu, a ti ih prevezi gore u Jeruzalem.”"},{"v":16,"t":"Salomon pobroji sve strance koji se zatekoše u Izraelovoj zemlji poslije popisa što ga bijaše proveo njegov otac David i nađe ih sto pedeset tri tisuće i šest stotina."},{"v":17,"t":"Od njih odredi sedamdeset tisuća nosača, osamdeset tisuća tesara u planini, tri tisuće i šest stotina ljudi da upravljaju radom naroda."}]},"3":{"hr":[{"v":1,"t":"Salomon tada poče graditi Dom Jahvi u Jeruzalemu, na Morijskoj gori, ondje gdje je njegov otac David imao viđenje. To je mjesto koje je pripravio David, gumno Jebusejca Ornana."},{"v":2,"t":"Salomon otpoče gradnju drugoga mjeseca četvrte godine svojega vladanja."},{"v":3,"t":"Ovo su temelji koje je Salomon postavio za gradnju Doma Božjega: šezdeset lakata u duljinu - po staroj mjeri lakta - a u širinu dvadeset lakata."},{"v":4,"t":"Trijem, koji je bio pred Domom, imao je, po širini ovoga potonjega, u dužinu dvadeset lakata, a visok je bio sto i dvadeset lakata. Obložio ga je iznutra čistim zlatom."},{"v":5,"t":"Veliku je dvoranu obložio čempresovinom, koju je prekrio čistim zlatom i postavio palme i cvjetne vijence."},{"v":6,"t":"Optočio je potom Dvoranu blistavim draguljima; zlato je bilo zlato parvajimsko."},{"v":7,"t":"Prekrio je njime Dvoranu: grede, pragove, zidove i vratna krila te izrezao kerubine po zidovima."},{"v":8,"t":"Potom sazda dvoranu Svetinje nad svetinjama. Bila je, prema hramskoj širini, dvadeset lakata duga i dvadeset lakata široka i obloži je sa šest stotina talenata suhog zlata."},{"v":9,"t":"Za čavle je dao na mjeru pedeset zlatnih šekela. I gornje je odaje obložio zlatom."},{"v":10,"t":"U dvorani Svetinje nad svetinjama napravi dva kerubina, liveno djelo. I njih obloži zlatom."},{"v":11,"t":"Krila kerubina bila su dvadeset lakata duga: jedno krilo od pet lakata dodirivaše hramski zid, a drugo od pet lakata doticaše krilo drugoga kerubina."},{"v":12,"t":"Tako je i krilo drugoga kerubina, od pet lakata, dodirivalo hramski zid, a drugo mu se krilo, od pet lakata, spajalo s krilom drugoga kerubina."},{"v":13,"t":"Raširena, krila kerubina imala su dvadeset lakata. Stajali su kerubini uspravno, lic-a okrenutih Dvorani."},{"v":14,"t":"Napravi zastor od ljubičastog baršuna, od grimiza, karmezina i bÓeza te na njemu izveze kerubine."},{"v":15,"t":"Pred Dvoranom napravi dva stupa dugačka trideset i pet lakata, a glavice im na vrhu pet lakata."},{"v":16,"t":"U Debiru on splete vijence te ih postavi navrh stupova i napravi sto mogranja koje postavi među vijence."},{"v":17,"t":"Postavi stupove pred Hekal, jedan zdesna, drugi slijeva, te nazva Jakin onaj zdesna, a Boaz onaj slijeva."}]},"4":{"hr":[{"v":1,"t":"Napravi tučani žrtvenik dugačak dvadeset lakata, širok dvadeset i visok deset."},{"v":2,"t":"Tada od rastaljene kovine izli more koje je od ruba do ruba mjerilo deset lakata; bilo je okruglo uokolo, pet lakata visoko, a u opsegu, mjereno vrpcom, imalo je trideset lakata."},{"v":3,"t":"Pod njim bijahu likovi volovski što ga opasivahu uokrug. Po deset ih je bilo na jednom laktu te okruživahu more uokolo; dva je reda bilo tih volova, salivenih s morem."},{"v":4,"t":"More je počivalo na dvanaest volova; tri su gledala na sjever, tri na zapad, tri na jug, tri na istok: more je stajalo na njima i svi su stražnjim dijelom bili okrenuti unutra."},{"v":5,"t":"Bilo je debelo pedalj, rub mu kao rub u čaše, kao cvijet, a moglo je primiti tri tisuće bata."},{"v":6,"t":"Napravi deset umivaonika i postavi ih pet zdesna, pet slijeva da se u njima pere; u njima su prali što je trebalo za paljenice; more je bilo namijenjeno svećenicima da se umivaju u njemu."},{"v":7,"t":"Napravi deset zlatnih svijećnjaka prema propisu i stavi ih u Hekal, pet s desne strane, pet s lijeve."},{"v":8,"t":"Onda napravi deset stolova i postavi ih u Hekalu, pet zdesna, a pet slijeva. Napravi stotinu zlatnih kotlića."},{"v":9,"t":"Onda načini trijem svećenički veliko dvorište s vratima koja prevuče tučem."},{"v":10,"t":"More stavi s desne strane prema jugoistoku."},{"v":11,"t":"Huram načini lonce, lopate i kotliće. Dovrši sav posao što ga je obavljao kralju Salomonu za Dom Božji:"},{"v":12,"t":"dva stupa; dvije glavice što su bile navrh stupova; dva opleta da prekriju dvije glavice što bijahu navrh stupova;"},{"v":13,"t":"četiri stotine mogranja za oba opleta; dva reda mogranja za svaki oplet da prekriju dvije glavice navrh stupova;"},{"v":14,"t":"deset podnožja i deset umivaonika na podnožjima;"},{"v":15,"t":"jedno more i dvanaest volova pod njim;"},{"v":16,"t":"lonce, lopate, viljuške i sav pribor za njih napravi od tuča Huram Abi kralju Salomonu za Dom Jahvin."},{"v":17,"t":"Kralj odredi da ih saliju u Jordanskoj ravnici, kod gaza Adame, između Sukota i Serede."},{"v":18,"t":"Salomon napravi tako mnogo tih predmeta da se nije mogla izmjeriti težina tuča."},{"v":19,"t":"Onda napravi sve predmete namijenjene Domu Božjemu: zlatni žrtvenik i stolove na kojima bjehu prineseni kruhovi,"},{"v":20,"t":"zlatne svijećnjake sa svjetiljkama od čistoga zlata što su se, po propisu, trebale paliti pred Debirom;"},{"v":21,"t":"cvjetove, svjetiljke i usekače od zlata; bilo je to čisto zlato;"},{"v":22,"t":"nožice, kotliće, mašice i kadionice od čistoga zlata; ulaz u Dom, nutarnja vrata - Svetinje nad svetinjama - i vrata Doma - Hekala - bila su zlatna."}]},"5":{"hr":[{"v":1,"t":"Tako bi priveden kraju posao što ga Salomon obavi za Dom Jahvin. Salomon unese sve svete darove oca svoga Davida - srebro, zlato i sve posuđe - i stavi ih u riznicu Božjega Doma."},{"v":2,"t":"Tada Salomon sazva u Jeruzalem sve Izraelove starješine, knezove plemenske i glavare obiteljske, da se prenese Kovčeg saveza Jahvina iz Davidova grada, to jest sa Siona."},{"v":3,"t":"Svi se ljudi Izraelovi sabraše pred kraljem na blagdan što je u sedmom mjesecu."},{"v":4,"t":"Kad se sastadoše sve Izraelove starješine, leviti ponesoše Kovčeg"},{"v":5,"t":"i Šator sastanka sa svim posvećenim priborom što bješe u Šatoru; svećenici ih i leviti prenesoše."},{"v":6,"t":"Potom kralj Salomon i sva izraelska zajednica što se sabra k njemu žrtvovaše pred Kovčegom toliko ovaca i goveda da se ne mogahu ni prebrojiti ni procijeniti."},{"v":7,"t":"Svećenici donesoše Kovčeg saveza Jahvina na njegovo mjesto, u Debir Doma, to jest u Svetinju nad svetinjama, pod krila kerubinÄa."},{"v":8,"t":"Kerubini su imali raširena krila nad mjestom gdje stajaše Kovčeg i zaklanjahu Kovčeg i njegove motke."},{"v":9,"t":"Motke su bile tako dugačke da su im se krajevi vidjeli iz Svetišta nasuprot Debiru, ali se nisu vidjele izvana i ondje stoje do dana današnjega."},{"v":10,"t":"U Kovčegu nije bilo ništa, osim dviju ploča koje metnu Mojsije na Horebu, gdje Jahve sklopi Savez s Izraelcima pošto iziđoše iz Egipta."},{"v":11,"t":"Svi svećenici izađoše iz Svetišta, jer su se svi nazočni svećenici posvetili bez obzira na redove."},{"v":12,"t":"Svi levitski pjevači, Asaf, Heman, Jedutun sa sinovima i braćom, stajahu obučeni u bÓez, s cimbalima, harfama i citrama, istočno od žrtvenika, a s njima sto i dvadeset svećenika koji su trubili u trube."},{"v":13,"t":"I dok su trubili i pjevali složno kao jedan i jednoglasno hvalili i slavili Jahvu, podižući glas uz trube, cimbale i druga glazbala, hvaleći Jahvu “jer je dobar i jer je vječna njegova ljubav”, oblak ispuni Dom Jahvin."},{"v":14,"t":"Svećenici ne mogoše od oblaka nastaviti službe: slava Jahvina ispuni Božji dom!"}]},"6":{"hr":[{"v":1,"t":"Tada reče Salomon: “Jahve odluči prebivati u tmastu oblaku,"},{"v":2,"t":"a ja ti sagradih uzvišen Dom da u njemu prebivaš zauvijek.”"},{"v":3,"t":"I, okrenuvši se, kralj blagoslovi sav izraelski zbor, a sav je izraelski zbor stajao."},{"v":4,"t":"Reče on: “Neka je blagoslovljen Jahve, Bog Izraelov, koji svojom rukom ispuni obećanje što ga na svoja usta dade ocu mome Davidu, rekavši:"},{"v":5,"t":"'Od dana kad izvedoh svoj narod iz egipatske zemlje nisam izabrao grada ni iz kojeg Izraelova plemena da se u njemu sagradi Dom gdje bi prebivalo moje Ime, niti sam izabrao ikoga da vlada nad mojim narodom izraelskim."},{"v":6,"t":"Ali sam izabrao Jeruzalem da u njemu obitava moje Ime i odabrao Davida da zapovijeda mojem narodu izraelskom.'"},{"v":7,"t":"Otac mi David naumi podići Dom Imenu Jahve, Boga Izraelova,"},{"v":8,"t":"ali mu Jahve reče: 'Naumio si podići Dom Imenu mojem, i dobro učini,"},{"v":9,"t":"ali nećeš ti podići toga Doma, nego tvoj sin koji izađe iz tvoga krila; on će podići Dom Imenu mojem.'"},{"v":10,"t":"Jahve ispuni obećanje svoje: naslijedio sam oca Davida i sjeo na prijestolje Izraelovo, kako obeća Jahve, podigao Dom Imenu Jahve, Boga Izraelova,"},{"v":11,"t":"i namjestio Kovčeg u kojem je Savez što ga Jahve sklopi sa sinovima Izraelovim.”"},{"v":12,"t":"Tada Salomon stupi, u nazočnosti svega zbora Izraelova, pred žrtvenik Jahvin i raširi ruke."},{"v":13,"t":"Salomon je, naime, bio napravio tučano podnožje, dugo pet lakata i široko pet lakata, a visoko tri lakta, i stavio ga nasred predvorja; stavši na nj, kleknuo je pred svim zborom Izraelovim i, raširivši ruke k nebu,"},{"v":14,"t":"rekao: “Jahve, Bože Izraelov! Nijedan ti bog nije sličan ni na nebesima ni na zemlji, tebi koji držiš Savez i ljubav svojim slugama što kroče pred tobom sa svim svojim srcem."},{"v":15,"t":"Sluzi svome Davidu, mojem ocu, ispunio si što si mu obećao. Što si obećao na svoja usta, ispunio si svojom rukom upravo danas."},{"v":16,"t":"Jahve, Bože Izraelov, sada ispuni svome sluzi, ocu mome Davidu, što si mu obećao kad si rekao: 'Neće ti preda mnom nestati nasljednika koji bi sjedio na izraelskom prijestolju, samo ako tvoji sinovi budu čuvali svoje putove hodeći po mojem zakonu kako si ti hodio preda mnom.'"},{"v":17,"t":"Jahve, Bože Izraelov, neka se sada dakle ispuni obećanje koje si dao svome sluzi Davidu!"},{"v":18,"t":"Ali zar će Bog doista boraviti s ljudima na zemlji? TÓa nebesa ni nebesa nad nebesima ne mogu ga obuhvatiti, a kamoli ovaj Dom što sam ga sagradio!"},{"v":19,"t":"Pomno počuj molitvu i vapaj svoga sluge, Jahve, Bože moj, te usliši prošnju i molitvu što je tvoj sluga k tebi upućuje!"},{"v":20,"t":"Neka tvoje oči obdan i obnoć budu otvorene nad ovim Domom, nad ovim mjestom za koje reče da ćeš u nj smjestiti svoje Ime. Usliši molitvu koju će sluga tvoj izmoliti na ovome mjestu."},{"v":21,"t":"I usliši molitvu sluge svoga i naroda svojega izraelskog koju bude upravljao prema ovome mjestu. Usliši s mjesta gdje prebivaš, s nebesa, usliši i oprosti!"},{"v":22,"t":"Ako tko zgriješi protiv bližnjega i bude mu naređeno da se zakune i zakletva dođe pred tvoj žrtvenik u ovom Domu,"},{"v":23,"t":"ti je čuj s neba, postupaj i sudi svojim slugama, osudi krivca okrećući njegova nedjela na njegovu glavu, a nevina oslobodi postupajući s njime po nevinosti njegovoj."},{"v":24,"t":"Ako narod tvoj poraze neprijatelji jer se ogriješio o tebe, ali se ipak k tebi obrati i proslavi Ime tvoje i u ovom se Domu pomoli i zavapije k tebi,"},{"v":25,"t":"onda ti čuj to s neba, oprosti grijehe svojem narodu izraelskom i dovedi ga natrag u zemlju koju si dao njima i njihovim očevima."},{"v":26,"t":"Ako se zatvori nebo i ne padne kiša jer su se ogriješili o tebe, pa ti se pomole na ovom mjestu i proslave Ime tvoje i obrate se od svojega grijeha kad ih ti poniziš,"},{"v":27,"t":"tada čuj s neba i oprosti grijeh svojim slugama i svojem izraelskom narodu, pokazujući mu valjan put kojim će ići, i pusti kišu na zemlju koju si narodu svojem dao u baštinu."},{"v":28,"t":"Kad u zemlji zavlada glad, kuga, snijet i rđa, kad navale skakavci i gusjenice, kad neprijatelj ovoga naroda pritisne koja od njegovih vrata ili kad udari kakva druga nevolja ili boleština,"},{"v":29,"t":"počuj svaku molitvu, svaki vapaj od kojega god čovjeka ili od cijeloga tvoga naroda izraelskog; ako svaki osjeti bol u srcu i raširi ruke k ovom Domu,"},{"v":30,"t":"usliši im molitvu i vapaj njihov u nebu gdje boraviš i oprosti i daj svakomu po njegovim putovima, jer ti poznaješ srce njegovo; jer ti jedini prozireš srca ljudi"},{"v":31,"t":"da te se boje idući tvojim putovima dokle god žive na zemlji što je ti dade našim očevima."},{"v":32,"t":"Pa i tuđinca, koji nije od tvojega naroda izraelskog, nego je stigao iz daleke zemlje radi veličine tvoga Imena i radi tvoje snažne ruke i podignute mišice, ako dođe i pomoli se u ovom Domu,"},{"v":33,"t":"usliši s neba, gdje prebivaš, usliši sve vapaje njegove da bi svi zemaljski narodi upoznali Ime tvoje i bojali te se kao narod tvoj izraelski i da znaju da je tvoje Ime prizvano nad ovaj Dom koji sam sagradio."},{"v":34,"t":"Kad narod tvoj krene na neprijatelja putem kojim ga ti uputiš i pomoli se tebi, okrenut gradu što si ga izabrao i prema Domu koji sam podigao tvome Imenu,"},{"v":35,"t":"usliši mu s neba molitvu i prošnju i učini mu pravdu."},{"v":36,"t":"Kad ti sagriješe, jer nema čovjeka koji ne griješi, a ti ih, rasrdiv se na njih, predaš neprijateljima da ih zarobe i odvedu kao roblje u daleku ili blizu zemlju,"},{"v":37,"t":"pa ako se pokaju srcem u zemlji u koju budu dovedeni te se obrate i počnu te moliti za milost u zemlji svojih osvajača govoreći: 'Zgriješili smo'"},{"v":38,"t":"i tako se obrate tebi svim srcem i svom dušom u zemlji svoga ropstva u koju budu dovedeni kao roblje, i pomole se okrenuti k zemlji što je ti dade njihovim očevima i prema gradu koji si odabrao i prema Domu što sam ga podigao tvom Imenu,"},{"v":39,"t":"usliši s neba, gdje prebivaš, njihovu molbu i njihove prošnje, učini im pravdu i oprosti svome narodu što ti je zgriješio."},{"v":40,"t":"Sada, Bože moj, neka tvoje oči budu otvorene i tvoje uši pažljive na molitve na ovom mjestu!"},{"v":41,"t":"Pa sada ustani, o Bože Jahve, pođi k svojem počivalištu, ti i Kovčeg tvoje snage; neka se obuku u spasenje tvoji svećenici, o Bože Jahve, i vjerni tvoji neka se raduju u sreći!"},{"v":42,"t":"Bože Jahve, ne odvrati lica od svog pomazanika, spomeni se milostÄi što ih dade sluzi svome Davidu!”"}]},"7":{"hr":[{"v":1,"t":"Kad Salomon dovrši molitvu, spusti se oganj s neba i spali paljenicu i klanice i slava Jahvina ispuni Dom."},{"v":2,"t":"Svećenici ne mogoše ući, jer slava Jahvina bješe ispunila Dom Jahvin."},{"v":3,"t":"Svi sinovi Izraelovi, videći gdje se oganj sa slavom Jahvinom spustio na Dom, padoše ničice k zemlji do kamenog poda; pokloniv se, počeše slaviti Jahvu “jer je dobar i jer je vječna njegova ljubav”."},{"v":4,"t":"Potom kralj i čitav narod stadoše žrtvovati žrtve pred Jahvom."},{"v":5,"t":"Kralj Salomon prinese za žrtvu dvadeset i dvije tisuće goveda, sto i dvadeset tisuća ovaca; i tako posvetiše Dom Jahvin i kralj i sav narod."},{"v":6,"t":"Dok su svećenici stajali na dužnostima, leviti su na glazbalima za Jahvine pjesme, što ih učini kralj David, slavili Jahvu “jer je vječna njegova ljubav”. Time je David preko njihovih ruku hvalio Jahvu. Pred njima su svećenici trubili u trube, dok su Izraelci stajali."},{"v":7,"t":"Salomon je posvetio i sredinu predvorja koje je pred Jahvinim Domom, jer je ondje prinio paljenice i pretilinu od pričesnica, jer na tučani žrtvenik koji bijaše napravio Salomon nisu mogle stati paljenice ni prinosi ni pretilina."},{"v":8,"t":"U to je doba Salomon svetkovao blagdan sedam dana i sav Izrael s njime, vrlo velik zbor, od Ulaza u Hamat pa do Egipatskoga potoka."},{"v":9,"t":"A osmoga su dana svetkovali svečani zbor, jer su posvetu žrtveniku svetkovali sedam dana i blagdan sedam dana."},{"v":10,"t":"Dvadeset trećega dana sedmoga mjeseca posla ljude k njihovim šatorima i odoše vesela i zadovoljna srca zbog dobra koje je Jahve učinio Davidu i Salomonu i svem narodu izraelskom."},{"v":11,"t":"Tako je Salomon dovršio Dom Jahvin i kraljevski dvor i izveo sve što god bješe zasnovano da izvrši u Domu Jahvinu i u svojem dvoru."},{"v":12,"t":"Potom se Jahve ukaza Salomonu noću i reče mu: “Uslišao sam tvoju molitvu i izabrao to mjesto da mi bude Dom žrtve."},{"v":13,"t":"Ako zatvorim nebo da ne bude dažda, ili zapovjedim skakavcima da popasu zemlju, ili pustim kugu na svoj narod,"},{"v":14,"t":"i ponizi se moj narod na koji je prizvano Ime moje i pomoli se i potraži lice moje i okani se zlih putova, ja ću ga tada uslišati s neba i oprostiti mu grijeh i izliječit ću mu zemlju."},{"v":15,"t":"Moje će oči biti otvorene i moje uši pažljive na molitvu s ovoga mjesta."},{"v":16,"t":"Sada sam, dakle, izabrao i posvetio ovaj Dom da ovdje bude Ime moje zauvijek i ovdje će sve dane biti moje oči i moje srce."},{"v":17,"t":"A ti, budeš li išao preda mnom kako ti je išao otac David, vršeći sve što sam ti zapovjedio i držeći se mojih uredaba i zakona,"},{"v":18,"t":"uzdržat ću tvoje kraljevsko prijestolje kako sam obećao tvome ocu Davidu govoreći: 'Neće ti ponestati nasljednika koji bi vladao u Izraelu.'"},{"v":19,"t":"Ali ako me ostavite i napustite uredbe i zapovijedi koje sam vam dao te otiđete i počnete služiti tuđim bogovima i klanjati im se,"},{"v":20,"t":"istjerat ću Izraelce iz svoje zemlje koju sam im dao i odbacit ću od sebe ovaj Dom koji sam posvetio svojem Imenu i učinit ću od njega priču i sramotu među svim narodima."},{"v":21,"t":"Tko god prođe mimo ovaj Dom koji bijaše preslavan zaprepastit će se od užasa i pitati: 'Zašto je Jahve tako učinio s ovom zemljom i s ovim Domom?'"},{"v":22,"t":"I odgovorit će mu se: 'Ostavili su Jahvu, Boga svojih otaca, koji ih je izveo iz Egipta, i okrenuli se tuđinskim bogovima, i klanjali im se, i služili im, i zato je Jahve pustio na njih sve ovo zlo.'”"}]},"8":{"hr":[{"v":1,"t":"A kad je prošlo dvadeset godina, za koliko je vremena Salomon podigao Jahvin Dom i svoj dvor,"},{"v":2,"t":"posagradio je Salomon gradove, koje je dao Salomonu Hiram, i naselio ondje Izraelove sinove."},{"v":3,"t":"Potom otiđe Salomon na Sopski Hamat i osvoji ga."},{"v":4,"t":"Sagradi Tadmor u pustinji i svakojaka mjesta za skladišta u Hamatu."},{"v":5,"t":"Sagradi i Gornji Bet Horon i Donji Bet Horon, tvrde gradove sa zidovima, vratima i prijevornicama;"},{"v":6,"t":"i Baalat, i sve gradove u kojima je imao skladišta, sve gradove za bojna kola i gradove za konjanike i što je god Salomon zaželio da gradi u Jeruzalemu i na Libanonu i po svoj zemlji svojega kraljevstva."},{"v":7,"t":"Svim preostalim Hetitima, Amorejcima, Perižanima, Hivijcima i Jebusejcima, koji nisu bili Izraelci,"},{"v":8,"t":"sinovima njihovim koji ostadoše iza njih u zemlji i koje Izraelci nisu zatrli - Salomon nametnu tlaku do današnjega dana."},{"v":9,"t":"Sinove Izraelove nije Salomon pretvarao u robove za posao, nego su bili vojnici, zapovjednici njegovih štitonoša i zapovjednici bojnih kola i konjice."},{"v":10,"t":"Bili su poglavari nad upravnicima, kojih je kralj Salomon imao dvjesta i pedeset, i upravljali su narodom."},{"v":11,"t":"Salomon preseli i faraonovu kćer iz Davidova grada u kuću koju joj bijaše sagradio, jer je mislio: “Neće moja žena živjeti u dvoru izraelskoga kralja Davida, jer je svet otkako je u nj došao Kovčeg Jahvin.”"},{"v":12,"t":"Tada Salomon poče prinositi paljenice Jahvi na Jahvinu žrtveniku što ga bijaše sagradio pred trijemom,"},{"v":13,"t":"i to koliko je trebalo iz dana u dan da prinese po Mojsijevoj zapovijedi, u subote, i na mlađake, i na blagdane tri puta u godini, na Blagdan beskvasnih kruhova, i na Blagdan sedmica, i na Blagdan sjenica."},{"v":14,"t":"Postavio je, po uredbi oca Davida, svećeničke redove po njihovoj službi i levitske po njihovim dužnostima da pjevaju hvale i da služe pred svećenicima, koliko treba iz dana u dan, i vratare po njihovim redovima na svakim vratima, jer je takva bila zapovijed Božjega čovjeka Davida."},{"v":15,"t":"Nisu odstupili od kraljeve zapovijedi za svećenike i levite ni u čemu, ni za riznice."},{"v":16,"t":"Tako se svršio sav Salomonov posao od dana kad je bio zasnovan Dom Jahvin pa dokle ga god nije dovršio. Tako bijaše dovršen Dom Jahvin."},{"v":17,"t":"Tada je Salomon otišao u Esjon-Geber i u Elat na morskoj obali u zemlji edomskoj."},{"v":18,"t":"A Hiram mu je poslao po slugama lađe i mornare vične moru te su otišli sa Salomonovim slugama u Ofir; uzeše odande četiri stotine i pedeset talenata zlata i donesoše ih kralju Salomonu."}]},"9":{"hr":[{"v":1,"t":"Uto kraljica od Sabe ču glas o Salomonu; hoteći iskušati Salomona zagonetkama, dođe u Jeruzalem s mnogobrojnom pratnjom i s devama koje su nosile miomirise, mnogo zlata i dragulja. Došavši k Salomonu, porazgovori se s njim o svemu što joj bijaše na srcu."},{"v":2,"t":"Salomon joj odgovori na sva pitanja; nije bilo Salomonu sakriveno ništa da joj ne bi umio objasniti."},{"v":3,"t":"Kad kraljica od Sabe vidje njegovu mudrost, dvor koji bijaše sagradio,"},{"v":4,"t":"jela na njegovu stolu, odaje njegove i dvorane, otmjenost njegove posluge i njihova odijela, i njegove peharnike i njihova odijela, i njegove paljenice koje je prinosio u Jahvinu domu, zastade joj dah."},{"v":5,"t":"Tada reče kralju: “Istina je bila što sam u svojoj zemlji čula o tebi i o tvojoj mudrosti."},{"v":6,"t":"Ali nisam htjela vjerovati što se pripovijeda dokle god nisam došla i vidjela na svoje oči; i doista, ni pola mi nije bilo rečeno o tvojoj velikoj mudrosti; nadvisio si glas koji sam slušala."},{"v":7,"t":"Blago tvojim ljudima i tvojim slugama koji stoje pred tobom i slušaju tvoju mudrost!"},{"v":8,"t":"Neka je blagoslovljen Jahve, tvoj Bog, komu si tako omilio da te postavio na svoje prijestolje da kraljuješ umjesto Jahve, svojega Boga, jer Bog tvoj ljubi Izraela da bi ga održao dovijeka; i zato je postavio tebe za kralja da činiš pravo i pravicu.”"},{"v":9,"t":"Dala je tada kralju sto i dvadeset zlatnih talenata i mnogo miomirisa i dragulja. Nikad više nije bilo takvih miomirisa kakve je kraljica od Sabe dala kralju Salomonu."},{"v":10,"t":"Hiramove sluge, koje su sa Salomonovim slugama donosile zlata iz Ofira, dovezle su također sandalovine i dragulja."},{"v":11,"t":"Kralj je napravio i citre i harfe za pjevače: nikad se prije nisu vidjele takve stvari u zemlji judejskoj."},{"v":12,"t":"Kralj Salomon dade kraljici od Sabe što je zaželjela i zatražila, izuzev ono što je sama donijela kralju. Potom ona krenu i sa slugama ode u svoju zemlju."},{"v":13,"t":"Zlato što je dolazilo Salomonu svake godine bilo je teško šest stotina šezdeset i šest zlatnih talenata,"},{"v":14,"t":"osim onoga što je dolazilo od trgovaca i putujućih prodavača. I svi su arapski kraljevi i zemaljski upravitelji Salomonu donosili zlato i srebro."},{"v":15,"t":"Kralj Salomon načini dvjesta štitova od kovanoga zlata; za svaki je štit upotrijebio šest stotina šekela kovanoga zlata;"},{"v":16,"t":"i načini trista štitića od kovanoga zlata; za svaki je štitić utrošio trista zlatnih šekela. Kralj ih je pohranio u kuću zvanu Libanonska šuma."},{"v":17,"t":"Kralj je napravio i veliko prijestolje od bjelokosti i obložio ga čistim zlatom."},{"v":18,"t":"Prijestolje je imalo šest stepenica i zlatno podnožje sastavljeno s prijestoljem, i ručice s obiju strana prijestolja, a kraj ručica stajala dva lava."},{"v":19,"t":"Dvanaest je lavova stajalo s obiju strana onih šest stepenica. Takvo što nije bilo izrađeno ni u jednom kraljevstvu."},{"v":20,"t":"Sve posude iz kojih je pio kralj Salomon bijahu zlatne i sve posuđe u kući zvanoj Libanonska šuma bijaše od suhoga zlata; srebro se smatralo bezvrijednim u Salomonovo vrijeme."},{"v":21,"t":"Kraljeve su lađe išle u Taršiš s Hiramovim slugama; svake treće godine vraćale su se i dolazile taršiške lađe donoseći zlato i srebro, slonovu kost, majmune i paune."},{"v":22,"t":"Tako je kralj Salomon natkrilio sve zemaljske kraljeve bogatstvom i mudrošću."},{"v":23,"t":"Svi su zemaljski kraljevi željeli vidjeti Salomona i čuti mudrost koju mu je Bog ulio u srce."},{"v":24,"t":"Svatko mu je donosio dar, srebrno i zlatno posuđe, haljine, oružje i miomirise, konje i mazge, iz godine u godinu."},{"v":25,"t":"Salomon je imao četiri tisuće konjskih jasala i bojnih kola i dvanaest tisuća konjanika, koje je rasporedio po gradovima bojnih kola i kod kralja u Jeruzalemu."},{"v":26,"t":"Vladao je nad svim kraljevima od Rijeke do zemlje filistejske i do egipatske međe."},{"v":27,"t":"Kralj je učinio da u Jeruzalemu bude srebra kao kamenja, a cedrova kao divljih smokava što rastu u Judejskoj nizini."},{"v":28,"t":"Salomon je uvozio konje iz Musrija i iz svih zemalja."},{"v":29,"t":"Ostala djela Salomonova, od prvih do posljednjih, zapisana su u povijesti proroka Natana, u proročkoj knjizi Šilonjanina Ahije i u proročkoj besjedi vidioca Adona o Nebatovu sinu Jeroboamu."},{"v":30,"t":"Salomon je vladao u Jeruzalemu nad svim Izraelom četrdeset godina."},{"v":31,"t":"Potom je počinuo kod otaca i sahranili su ga u gradu oca mu Davida, a na njegovo se mjesto zakraljio sin mu Roboam."}]},"10":{"hr":[{"v":1,"t":"Tada Roboam ode u Šekem, jer su u Šekem došli svi Izraelci da ga zakralje."},{"v":2,"t":"Čim to ču Nebatov sin Jeroboam - koji je bio u Egiptu kamo bijaše pobjegao pred kraljem Salomonom - vrati se iz Egipta,"},{"v":3,"t":"jer bijahu poslali po nj i dozvali ga. Kad dođoše Jeroboam i sav zbor Izraelov, rekoše Roboamu:"},{"v":4,"t":"“Tvoj nam je otac nametnuo težak jaram, ti nam sada olakšaj tešku službu svoga oca i teški jaram koji metnu na nas, pa ćemo ti služiti.”"},{"v":5,"t":"On im odgovori: “Za tri dana dođite opet k meni.” I narod ode."},{"v":6,"t":"Tada se kralj Roboam posavjetova sa starcima koji su služili njegovu ocu Salomonu dok je bio živ i upita ih: “Što savjetujete da odgovorim ovome narodu?”"},{"v":7,"t":"A oni mu odgovoriše: “Ako udovoljiš tim ljudima, budeš im blagonaklon i odgovoriš im lijepim riječima, oni će ti uvijek biti sluge.”"},{"v":8,"t":"Ali on odbaci savjet što mu ga dadoše starci i posavjetova se s mladićima koji su odrasli s njim i bili mu u službi."},{"v":9,"t":"Upita ih: “Što savjetujete da odgovorim ovomu narodu koji mi reče: 'Olakšaj jaram što nam ga nametnu tvoj otac!'”"},{"v":10,"t":"Odgovoriše mu mladići koji bijahu s njim odrasli: “Narodu koji ti je rekao 'Tvoj nam je otac nametnuo jaram, a ti nam ga olakšaj', odvrati ovako: 'Moj je mali prst deblji od bedara moga oca!"},{"v":11,"t":"Dakle, moj vam je otac nametnuo težak jaram, a ja ću još otežati vaš jaram; moj vas je otac šibao bičevima, a ja ću vas šibati bičevima sa željeznim štipavcima.'”"},{"v":12,"t":"Trećega dana dođe Jeroboam i sav narod k Roboamu, jer im kralj bijaše naredio: “Vratite se k meni trećega dana.”"},{"v":13,"t":"Kralj im oštro odgovori; odbacivši savjet starijih,"},{"v":14,"t":"odvrati po savjetu mladih: “Moj je otac otežao vaš jaram, a ja ću još dometnuti na nj; moj vas je otac šibao bičevima, a ja ću vas šibati bičevima sa željeznim štipavcima.”"},{"v":15,"t":"Kralj, dakle, ne htjede poslušati naroda, jer tako upriliči Bog da se ispuni riječ što je preko Šilonjanina Ahije kaza Nabatovu sinu Jeroboamu."},{"v":16,"t":"Kad Izraelci vidješe gdje se kralj oglušio, odgovori mu narod: “Kakav dio mi imamo s Davidom? Mi nemamo baštine s Jišajevim sinom! U šatore, Izraele! Sad se, Davide, brini za svoj dom!” I sav Izrael ode pod svoje šatore."},{"v":17,"t":"Roboam zavlada samo nad Izraelovim sinovima koji su živjeli po judejskim gradovima."},{"v":18,"t":"Potom kralj Roboam posla Adorama, nadstojnika za tlaku, ali ga Izraelci kamenovaše i on umrije; a kralj se Roboam brže-bolje pope na kola te pobježe u Jeruzalem."},{"v":19,"t":"Tako se Izrael odijelio od doma Davidova sve do danas."}]},"11":{"hr":[{"v":1,"t":"Došavši u Jeruzalem, skupi sav dom Judin i Benjaminov, sto i osamdeset tisuća vrsnih ratnika, da udare na Izraela i da Roboamu vrate kraljevstvo."},{"v":2,"t":"Ali dođe Jahvina riječ Božjem čovjeku Šemaji:"},{"v":3,"t":"“Kaži Salomonovu sinu Roboamu, judejskomu kralju, i svim Izraelcima u Judinu i Benjaminovu plemenu:"},{"v":4,"t":"Ovako veli Jahve: 'Ne idite se tući s braćom! Neka se svatko vrati svojoj kući, jer je ovo poteklo od mene.'” I oni poslušaše riječ Jahvinu, vratiše se i ne udariše na Jeroboama."},{"v":5,"t":"Roboam, stolujući u Jeruzalemu, poče dizati tvrde gradove po Judeji."},{"v":6,"t":"Tako je sagradio Betlehem, Etam, Tekou,"},{"v":7,"t":"Bet Sur, Sokon, Adulam,"},{"v":8,"t":"Gat, Maresu, Zif,"},{"v":9,"t":"Adorajim, Lakiš, Azeku,"},{"v":10,"t":"Soru, Ajalon i Hebron, tvrde gradove u Judinu i Benjaminovu plemenu."},{"v":11,"t":"Utvrdivši gradove, postavi im zapovjednike i dovuče zalihe hrane, ulja i vina;"},{"v":12,"t":"u svaki pojedini grad stavi štitova i kopalja i utvrdi ih vrlo jako. Tako je on imao Judino i Benjaminovo pleme."},{"v":13,"t":"Svećenici i leviti, koji su bili po svem Izraelu, pristupiše k njemu iz svih krajeva."},{"v":14,"t":"Leviti ostaviše pašnjake i posjed te otiđoše u Judeju i Jeruzalem, jer ih je bio odbacio Jeroboam i njegovi sinovi da ne obavljaju svećeničku službu Jahvi,"},{"v":15,"t":"a postavio je svećenike za uzvišice, za jarce i za telad koju je napravio."},{"v":16,"t":"Za njima su iz svih izraelskih plemena dolazili u Jeruzalem da žrtvuju Jahvi, Bogu svojih otaca, oni koji su srcem tražili Jahvu, Boga Izraelova."},{"v":17,"t":"Tako su utvrdili judejsko kraljevstvo i osokolili Salomonova sina Roboama za tri godine, jer su tri godine živjeli poput Davida i Salomona."},{"v":18,"t":"Roboam je sebi uzeo za žemu Mahalatu, kćer Davidova sina Jerimota, i Abihajilu, kćer Jišajeva sina Eliaba,"},{"v":19,"t":"koja mu rodi sinove: Jeuša, Šemarju i Zahama."},{"v":20,"t":"A poslije nje oženio se Abšalomovom kćerju Maakom, koja mu rodi Abiju, Etaja, Zizu i Šelomita."},{"v":21,"t":"Roboam je ljubio Abšalomovu kćer Maaku više od svih svojih žena i inoča, iako je uzeo osamnaest žena i šezdeset inoča i rodio dvadeset i osam sinova i šezdeset kćeri."},{"v":22,"t":"I Roboam postavi Maakina sina Abiju za poglavara i kneza nad njegovom braćom, jer ga je naumio postaviti za kralja."},{"v":23,"t":"I, mudro radeći, razmjesti sinove po svim judejskim i Benjaminovim krajevima, po svim tvrdim gradovima, davši im hrane izobila i poženivši ih sa mnogo žena."}]},"12":{"hr":[{"v":1,"t":"Kad je Roboam utvrdio kraljevstvo i ojačao, napustio je Jahvin zakon i on i sav Izrael s njim."},{"v":2,"t":"Ali pete godine Roboamova kraljevanja navali egipatski kralj Šišak na Jeruzalem, koji se bijaše iznevjerio Jahvi."},{"v":3,"t":"Došao je sa tisuću i dvjesta bojnih kola i sa šezdeset tisuća konjanika, a narodu koji je došao s njim iz Egipta - Libijcima, Sukijcima i Etiopljanima - nije bilo broja."},{"v":4,"t":"Osvojivši tvrde judejske gradove, dopro je do Jeruzalema."},{"v":5,"t":"Tada dođe prorok Šemaja k Roboamu i judejskim knezovima, koji se bijahu skupili u Jeruzalemu bježeći od Šišaka, i reče im: “Ovako veli Jahve: 'Vi ste ostavili mene, pa i ja ostavljam vas u ruke Šišaku.'”"},{"v":6,"t":"Tada se poniziše izraelski knezovi i kralj i rekoše: “Pravedan je Jahve!”"},{"v":7,"t":"Kad ih Jahve vidje gdje se poniziše, dođe njegova riječ Šemaji: “Ponizili su se; neću ih uništiti, nego ću im uskoro dati spasenje te se moja srdžba neće oboriti na Jeruzalem preko Šišaka."},{"v":8,"t":"Bit će mu sluge, da vide što znači služiti meni, a što zemaljskim kraljevstvima.”"},{"v":9,"t":"Tako egipatski kralj Šišak navali na Jeruzalem, opljačka blago iz Doma Jahvina i riznicu kraljeva dvora; sve je uzeo; uze i zlatne štitove što ih bijaše napravio Salomon."},{"v":10,"t":"Namjesto njih kralj Roboam napravi tučane štitove i povjeri ih zapovjednicima straže koja je čuvala vrata kraljevskoga dvora."},{"v":11,"t":"Kad je god kralj išao u Dom Jahvin, stražari su ih uzimali, a poslije ih vraćali u stražaru."},{"v":12,"t":"Kad se, dakle, ponizio, odvratio se od njega Jahvin gnjev te ga nije sasvim uništio, jer i u Judeji bijaše dobra."},{"v":13,"t":"Potom se kralj Roboam utvrdi u Jeruzalemu i stade kraljevati. Roboamu je bila četrdeset i jedna godina kad se zakraljio, a sedamnaest je godina kraljevao u Jeruzalemu, u gradu koji Jahve izabra između svih izraelskih plemena da ondje postavi Ime svoje. Majka mu se zvala Naama, a bila je Amonka."},{"v":14,"t":"Činio je zlo, jer nije pregnuo srcem da traži Jahvu."},{"v":15,"t":"Roboamova prva i posljednja djela - i ratovi koji su se neprestano vodili između Roboama i Jeroboama - zapisani su u povijesti proroka Šemaje i u plemenskom popisu vidioca Adona."},{"v":16,"t":"Potom Roboam počinu sa svojim ocima i bi sahranjen u Davidovu gradu; na njegovo se mjesto zakraljio sin mu Abija."}]},"13":{"hr":[{"v":1,"t":"Osamnaeste godine Jeroboamova kraljevanja zakralji se Abija nad Judejom."},{"v":2,"t":"Tri je godine kraljevao u Jeruzalemu. Materi mu je bilo ime Mikaja, Urielova kći iz Gabe. Tada izbi rat između Abije i Jeroboama."},{"v":3,"t":"Abija je izašao u boj s hrabrim ratnicima, sa četiri stotine tisuća izabranih junaka; Jeroboam je svrstao u bojni red protiv njega osam stotina tisuća ljudi, sve biranih junaka."},{"v":4,"t":"Abija je stao na vrh Semarajimske gore u Efrajimovu gorju i rekao: “Čujte me, Jeroboame i sav Izraele!"},{"v":5,"t":"Ne znate li da je Jahve, Bog Izraelov, predao Davidu kraljevstvo nad Izraelom zauvijek, njemu i njegovim sinovima, osoljenim savezom?"},{"v":6,"t":"Ali se podigao Nebatov sin Jeroboam, sluga Davidova sina Salomona, i pobunio se protiv gospodara."},{"v":7,"t":"Skupili su se oko njega ljudi praznovi i nevaljalci i stali prkositi Salomonovu sinu Roboamu, koji je bio mlad i strašljiva srca te se nije umio hrabro braniti od njih."},{"v":8,"t":"Pa sada mislite da se možete oprijeti Jahvinu kraljevstvu što je u ruci Davidovih sinova jer vas je veliko mnoštvo i imate kod sebe zlatnu telad koju vam je napravio Jeroboam da vam budu bogovi."},{"v":9,"t":"Otjerali ste Jahvine svećenike, Aronove sinove i levite, i postavili sebi svećenike kao drugi zemaljski narodi. Tko je god došao s juncem i sa sedam ovnova, postao je svećenik vašim ništavim bogovima."},{"v":10,"t":"Nama je Bog Jahve, nismo ga ostavili, a svećenici koji služe Jahvi jesu Aronovi sinovi i leviti u svojem poslu."},{"v":11,"t":"Pale Jahvi na kad paljenice svakoga jutra i svake večeri s mirisnim kadom, postavljaju kruhove na čist stol i upaljuju svake večeri zlatan svijećnjak sa svijećama; jer mi držimo naredbu Jahve, svojega Boga, a vi ste ga ostavili."},{"v":12,"t":"Zato je, evo, nama na čelu Bog i njegovi svećenici s glasnim trubama da gromko trube protiv vas. Izraelovi sinovi, ne udarajte na Jahvu, Boga svojih otaca, jer nećete imati sreće!”"},{"v":13,"t":"Ali Jeroboam zavede zasjedu da im dođe za leđa; tako su Judejcima bili jedni sprijeda, a zasjeda straga."},{"v":14,"t":"Kad se Judejci obazreše, a ono, gle, boj im bješe sprijeda i otraga. Tada zavapiše k Jahvi, a svećenici stadoše trubiti u trube."},{"v":15,"t":"Uto Judejci snažno povikaše, a kad su počeli vikati, Bog razbi Jeroboama i sav Izrael pred Abijom i Judejcima."},{"v":16,"t":"Izraelovi sinovi pobjegoše pred Judejcima i Bog ih predade njima u ruke."},{"v":17,"t":"Abija je s narodom učinio velik pokolj među njima te je od Izraela palo pobijenih pet stotina tisuća izabranih ljudi."},{"v":18,"t":"Tako su sinovi Izraelovi bili poniženi u to vrijeme, a Judini su sinovi ojačali, jer su se oslonili na Jahvu, Boga svojih otaca."},{"v":19,"t":"Abija je potjerao Jeroboama i osvojio od njega gradove Betel sa selima, Ješanu sa selima i Efron sa selima."},{"v":20,"t":"Jeroboam se više nije oporavio za Abijina života; Jahve ga je udario tako da je umro."},{"v":21,"t":"Abija se utvrdio i uzeo sebi četrnaest žena te je rodio dvadeset i dva sina i šesnaest kćeri."},{"v":22,"t":"A ostali Abijini doživljaji i njegovi pothvati i besjede zapisani su u tumačenju proroka Adona."},{"v":23,"t":"Potom Abija počinu kraj svojih otaca. Sahraniše ga u Davidovu gradu; na njegovo se mjesto zakralji sin mu Asa. Za njegovih je dana zemlja bila mirna deset godina."}]},"14":{"hr":[{"v":1,"t":"Asa je činio što je dobro i pravo u očima Jahve, njegova Boga."},{"v":2,"t":"Uklonio je tuđinske žrtvenike i uzvišice, polomio stupove i razbio ašere."},{"v":3,"t":"Naredio je Judejcima da traže Jahvu, Boga svojih otaca, da se drže zakona i zapovijedi."},{"v":4,"t":"Uklonio je iz svih judejskih gradova uzvišice i sunčane stupove, a kraljevstvo je bilo mirno za njegova vremena."},{"v":5,"t":"Sagradio je tvrde gradove u Judeji, jer je zemlja bila mirna. Nitko se nije zaratio na nj onih godina, jer mu je Jahve dao mir."},{"v":6,"t":"Zato je Asa rekao Judejcima: “Da pogradimo ove gradove i da ih opašemo zidom i kulama, vratima i prijevornicama; još je zemlja pred nama naša, jer smo tražili Jahvu, svoga Boga; tražili smo ga, i on nam je dao mir odasvud uokolo!” Tako su gradili i bili sretni."},{"v":7,"t":"Asa je imao vojske trista tisuća ljudi između Judejaca koji su nosili štit i koplje, a od Benjaminova plemena dvjesta i osamdeset tisuća koji su nosili štit i zapinjali luk. Svi su bili hrabri junaci."},{"v":8,"t":"Izašao je na njih Etiopljanin Zerah sa tisuću tisuća vojnika i tri stotine bojnih kola i došao do Mareše."},{"v":9,"t":"Asa je izašao preda nj; svrstali su se u bojni red u Sefatskoj dolini kod Mareše."},{"v":10,"t":"Asa zavapi k Jahvi, Bogu svome: “O Jahve, tebi je ništa pomoći silnome ili nejakome! Pomozi nam, o Jahve, Bože naš, jer se na te oslanjamo i u tvoje smo ime izišli na ovo mnoštvo! Jahve, ti si Bog naš, ne daj snažnu čovjeku protiv sebe!”"},{"v":11,"t":"Jahve razbi Etiopljane pred Asom i pred Judejcima te Etiopljani pobjegoše."},{"v":12,"t":"Asa ih je s narodom koji bijaše s njim potjerao sve do Gerara. Etiopljani su popadali, tako da nijedan nije ostao živ jer ih je satro Jahve i njegove čete; i one su odnijele vrlo velik plijen."},{"v":13,"t":"Osvojile su sve gradove oko Gerara jer je Jahvin strah došao na njih; oplijenile su sve te gradove, jer je u njima bilo mnogo plijena."},{"v":14,"t":"Poharale su i šatore za stoku i zaplijenile mnoštvo sitne stoke i deva; a onda su se vratile u Jeruzalem."}]},"15":{"hr":[{"v":1,"t":"Tada duh Božji dođe na Odedova sina Azarju."},{"v":2,"t":"On je izišao pred Asu i rekao mu: “Čujte me, Asa i sve Judino i Benjaminovo pleme! Jahve je s vama jer ste vi s njime; i ako ga budete tražili, naći ćete ga; ako li ga ostavite, i on će ostaviti vas."},{"v":3,"t":"Dugo su Izraelci bili bez pravoga Boga i bez svećenika-učitelja i bez Zakona."},{"v":4,"t":"Kad su se u nevolji obratili Jahvi, Bogu Izraelovu, i stali ga tražiti, našli su ga."},{"v":5,"t":"U ona vremena nitko nije mogao na miru ni izlaziti ni dolaziti, jer su veliki nemiri vladali među svim zemaljskim stanovnicima."},{"v":6,"t":"Udarao je narod na narod, grad na grad, jer ih je Jahve smeo svakojakom nevoljom."},{"v":7,"t":"Ali vi budite hrabri i neka vam ne klonu ruke, jer ima nagrada za vaša djela.”"},{"v":8,"t":"Čuvši te riječi i proročku besjedu proroka Odeda, Asa se ohrabri i ukloni idolske gadove iz cijele Judine i Benjaminove zemlje i iz gradova koje je bio osvojio u Efrajimovoj gori. Obnovio je i Jahvin žrtvenik koji je bio pred Jahvinim trijemom."},{"v":9,"t":"Onda je skupio sve Judino i Benjaminovo pleme i došljake koji su bili kod njih od Efrajimova, Manašeova i Šimunova plemena, jer ih je mnogo prebjeglo k njemu od Izraelaca kad su vidjeli da je s njim Jahve, njegov Bog."},{"v":10,"t":"I skupili su se u Jeruzalemu trećega mjeseca petnaeste godine Asina kraljevanja."},{"v":11,"t":"Onoga su dana prinijeli Jahvi žrtve od plijena koji su dognali, sedam stotina goveda i sedam tisuća sitne stoke."},{"v":12,"t":"Zavjetovaše se da će tražiti Jahvu, Boga svojih otaca, svim srcem i svom dušom."},{"v":13,"t":"A tko god ne bi tražio Jahvu, Izraelova Boga, da se pogubi, bio malen ili velik, čovjek ili žena."},{"v":14,"t":"Zakleli su se Jahvi iza glasa i uz gromki poklik, uz trube i rogove."},{"v":15,"t":"Svi su se Judejci radovali zbog te zakletve jer su se iz svega srca zakleli i od sve su ga svoje volje tražili i našli ga. Jahve im je dao mir odasvud uokolo."},{"v":16,"t":"I svoju mater Maaku ukloni kralj Asa s vlasti jer je bila načinila gada Ašeri. Asa je sasjekao njezina gada, satro ga i spalio u potoku Kidronu."},{"v":17,"t":"Ali uzvišice nisu bile uklonjene iz Izraela. Ipak je Asino srce bilo privrženo Jahvi svega njegova života."},{"v":18,"t":"Unio je u Dom Božji posvećene darove svoga oca i svoje: srebro i zlato i posuđe."},{"v":19,"t":"Nije bilo rata sve do trideset i pete godine Asina kraljevanja."}]},"16":{"hr":[{"v":1,"t":"Trideset i šeste godine Asina kraljevanja navali izraelski kralj Baša na Judeju i stade utvrđivati Ramu da spriječi svako kretanje judejskom kralju Asi."},{"v":2,"t":"Asa tada uze srebra i zlata iz riznice Doma Jahvina i kraljevskoga dvora i posla aramejskome kralju Ben-Hadadu, koji je stolovao u Damasku, i poruči mu:"},{"v":3,"t":"“Neka bude savez između mene i tebe i između moga i tvoga oca; evo, šaljem ti na dar srebra i zlata, hajde, raskini savez s izraelskim kraljem Bašom da bi otišao od mene.”"},{"v":4,"t":"Ben-Hadad posluša kralja Asu i posla svoje vojskovođe na izraelske gradove te oni pokoriše Ijon, Dan, Abel Majinu i sve Naftalijeve gradove-skladišta."},{"v":5,"t":"A kada to Baša dozna, presta utvrđivati Ramu i obustavi posao."},{"v":6,"t":"Tada kralj Asa sazva sve Judejce i oni odnesoše kamenje i drvo kojima je Baša utvrđivao Ramu, pa time utvrdiše Gebu i Mispu."},{"v":7,"t":"U to vrijeme dođe vidjelac Hanani k judejskom kralju Asi i reče mu: “Budući da si se oslonio na aramejskoga kralja, a nisi se oslonio na Jahvu, Boga svoga, vojska aramejskoga kralja izmakla ti je iz ruke."},{"v":8,"t":"Nisu li Etiopljani i Libijci imali silne čete sa vrlo mnogo bojnih kola i konjanika? Pa kad si se oslonio na Jahvu, predao ti ih je u ruke."},{"v":9,"t":"Jer Jahve svojim očima gleda po svoj zemlji da bi se ohrabrili oni kojima je srce iskreno prema njemu. Ludo si u tome radio, zato će se od sada dizati ratovi na te.”"},{"v":10,"t":"Tada se Asa razgnjevi na vidioca i baci ga u tamnicu, jer se razjario na nj. U to je vrijeme Asa potlačio i neke iz naroda."},{"v":11,"t":"I eto, Asina djela, od prvoga do posljednjeg, zapisana su u Knjizi o judejskim i izraelskim kraljevima."},{"v":12,"t":"Razbolio se trideset i devete godine kraljevanja, od nogu, te mu se bolest veoma pogoršala, ali ni u bolesti nije tražio Jahvu nego liječnike."},{"v":13,"t":"Tako Asa počinu sa svojim ocima i umrije četrdeset i prve godine svoga kraljevanja."},{"v":14,"t":"Sahranili su ga u grobnici koju bijaše iskopao sebi u Davidovu gradu i položili ga na odar što ga bijaše napunio miomirisima i mastima, zgotovljenima mastilačkom vještinom, i spalili mu ih vrlo mnogo."}]},"17":{"hr":[{"v":1,"t":"Onda se na njegovo mjesto zakralji sin mu Jošafat; on pokaza svoju silu protiv Izraela."},{"v":2,"t":"Razmjestio je vojsku po svim utvrđenim judejskim gradovima i postavio namjesnike po judejskoj zemlji i po Efrajimovim gradovima, koje bijaše zauzeo otac mu Asa."},{"v":3,"t":"Jahve je bio s Jošafatom jer je hodio pravim putovima svoga oca Davida i nije tražio baala."},{"v":4,"t":"Tražio je Boga svojih otaca i hodio po njegovim zapovijedima, ne čineći kao Izraelovi sinovi."},{"v":5,"t":"Zato je Jahve utvrdio kraljevstvo u njegovoj ruci, pa su svi Judejci davali Jošafatu danak, tako da je stekao veliko bogatstvo i slavu."},{"v":6,"t":"Njegovo se srce hrabrilo na Jahvinim putovima, pa je uklonio još i uzvišice i ašere iz Judeje."},{"v":7,"t":"Treće godine kraljevanja posla knezove Ben-Hajila, Obadju, Zahariju, Netanela i Miheja da uče po judejskim gradovima."},{"v":8,"t":"I s njima levite: Šemaju, Netaniju, Zebadju, Asahela, Šemiramota, Jonatana, Adoniju, Tobiju i Tob Adoniju; a s njima svećenike Elišamu i Jorama."},{"v":9,"t":"Poučavali su po Judeji noseći sa sobom Knjigu Zakona Jahvina i obilazili sve judejske gradove učeći narod."},{"v":10,"t":"Jahvin je strah spopao sva zemaljska kraljevstva oko Judeje, tako da nisu smjela zaratiti na Jošafata."},{"v":11,"t":"Sami su mu neki Filistejci donosili darove i novčani danak, a Arapi mu dogonili sitnu stoku: po sedam tisuća i sedam stotina ovnova te sedam tisuća i sedam stotina jaraca."},{"v":12,"t":"Tako je Jošafat sve više napredovao dok ne postade vrlo velik. Sazidao je u Judeji kule i gradove-skladišta."},{"v":13,"t":"Imao je mnogo zaliha u judejskim gradovima, a hrabrih junaka u Jeruzalemu."},{"v":14,"t":"Evo njihova popisa po obiteljima: od Judina plemena tisućnici: vojvoda Adna i s njim trista tisuća hrabrih junaka;"},{"v":15,"t":"do njega vojvoda Johanan i s njim dvjesta i osamdeset tisuća;"},{"v":16,"t":"za njim Zikrijev sin Amasja, koji se spremno stavio u Jahvinu službu, a s njim dvjesta tisuća hrabrih junaka."},{"v":17,"t":"Od Benjaminova plemena: hrabri junak Eliada i s njim dvjesta tisuća ljudi naoružanih lukom i štitom;"},{"v":18,"t":"za njim Jehozabad i s njim sto i osamdeset tisuća pripravnih za boj."},{"v":19,"t":"To su oni koji su služili kralju, ne brojeći one što ih je kralj namjestio u tvrdim gradovima po svoj Judeji."}]},"18":{"hr":[{"v":1,"t":"Jošafat je stekao veliko bogatstvo i slavu te se sprijateljio s Ahabom."},{"v":2,"t":"Poslije nekoliko godina došao je k Ahabu u Samariju. Ahab nakla mnogo sitne stoke i goveda njemu i ljudima što su bili s njim i nagovaraše ga da pođe na Ramot Gilead."},{"v":3,"t":"Izraelski kralj Ahab upita judejskoga kralja Jošafata: “Hoćeš li poći sa mnom na Ramot Gilead?” On odgovori: “Ja sam kao i ti, moj je narod kao i tvoj; s tobom ćemo u rat.”"},{"v":4,"t":"Jošafat još reče kralju izraelskom: “De, posavjetuj se prije s Jahvom!”"},{"v":5,"t":"Tada kralj izraelski sakupi proroke, njih četiri stotine, i upita ih: “Hoćemo li zavojštiti na Ramot Gilead ili da se okanim toga?” Oni odgovoriše: “Idi, jer će ga Bog predati kralju u ruke.”"},{"v":6,"t":"Ali Jošafat upita: “Ima li ovdje još koji prorok Jahvin da i njega upitamo?”"},{"v":7,"t":"Kralj izraelski odgovori Jošafatu: “Ima još jedan čovjek preko koga bismo mogli upitati Jahvu, ali ga mrzim jer mi ne proriče dobra nego uvijek samo zlo; to je Mihej, sin Jimlin.” Jošafat reče: “Neka kralj ne govori tako!”"},{"v":8,"t":"Tada kralj izraelski dozva jednoga dvoranina i reče mu: “Brže dovedi Jimlina sina Miheja!”"},{"v":9,"t":"Izraelski kralj i judejski kralj Jošafat sjedili su svaki na svojem prijestolju, u svečanim haljinama, na gumnu pred Samarijskim vratima, a proroci proricali pred njima."},{"v":10,"t":"Kenaanin sin Sidkija napravi sebi željezne rogove i reče: “Ovako veli Jahve: njima ćeš bosti Aramejce dokle ih god ne zatreš.”"},{"v":11,"t":"Tako su i svi drugi proroci proricali govoreći: “Idi na Ramot Gilead, uspjet ćeš: Jahve će ga predati kralju u ruke.”"},{"v":12,"t":"Glasnik koji bijaše otišao da zove Miheja reče mu: “Evo, svi proroci složno proriču dobro kralju. Govori i ti kao jedan od njih i proreci uspjeh!”"},{"v":13,"t":"Ali Mihej odvrati: “Živoga mi Jahve, govorit ću ono što mi Bog kaže!”"},{"v":14,"t":"Kad dođe pred kralja, upita ga kralj: “Miheju, da pođem u rat na Ramot Gilead ili da se okanim toga?” On odgovori: “Idite i uspjet ćete, jer će vam se predati u ruke!”"},{"v":15,"t":"Na to mu kralj reče: “Koliko ću te puta zaklinjati da mi kažeš samo istinu u Jahvino ime?”"},{"v":16,"t":"Tada Mihej odgovori: “Sav Izrael vidim rasut po gorama kao stado bez pastira. I Jahve veli: 'Nemaju više gospodara, neka se u miru kući vrate!'”"},{"v":17,"t":"Tada izraelski kralj reče Jošafatu: “Nisam li ti rekao da mi neće proreći dobro nego zlo?”"},{"v":18,"t":"A Mihej reče: “Zato čujte riječ Jahvinu. Vidio sam Jahvu gdje sjedi na prijestolju, a sva mu vojska nebeska stajaše zdesna i slijeva."},{"v":19,"t":"Jahve upita: 'Tko će zavesti izraelskoga kralja Ahaba da otiđe i padne u Ramot Gileadu?' Jedan reče ovo, drugi ono."},{"v":20,"t":"Tada uđe jedan duh, stade pred Jahvu i reče: 'Ja ću ga zavesti!' Jahve ga upita: 'Kako?'"},{"v":21,"t":"On odvrati: 'Izaći ću i bit ću lažljiv duh u ustima svih njegovih proroka.' Jahve mu reče: 'Ti ćeš ga zavesti. I uspjet ćeš. Idi i učini tako!'"},{"v":22,"t":"Tako je, evo, Jahve stavio lažljiva duha u usta tvojim prorocima; ali ti Jahve navješćuje zlo.”"},{"v":23,"t":"Tada pristupi Kenaanin sin Sidkija i udari Miheja po obrazu pitajući: “Zar je Jahvin duh mene napustio da bi govorio s tobom?”"},{"v":24,"t":"Mihej odvrati: “Vidjet ćeš onoga dana kad budeš bježao iz sobe u sobu da se sakriješ.”"},{"v":25,"t":"Tada izraelski kralj naredi: “Uhvatite Miheja i odvedite ga gradskom zapovjedniku Amonu i kraljeviću Joašu."},{"v":26,"t":"Recite im: 'Ovako veli kralj: Bacite ovoga u tamnicu i držite ga na suhu kruhu i vodi dok se sretno ne vratim.'”"},{"v":27,"t":"Mihej reče: “Ako se doista sretno vratiš, onda nije Jahve govorio iz mene!” i nadoda: “Čujte, svi puci!”"},{"v":28,"t":"Izraelski kralj i judejski kralj Jošafat krenuše na Ramot Gilead."},{"v":29,"t":"Izraelski kralj reče Jošafatu: “Ja ću se preobući i onda ući u boj, a ti ostani u svojoj odjeći!” Preobuče se tada izraelski kralj i oni krenuše u boj."},{"v":30,"t":"Aramejski kralj naredi zapovjednicima bojnih kola: “Ne udarajte ni na maloga ni na velikoga nego jedino na izraelskoga kralja!”"},{"v":31,"t":"Kad zapovjednici bojnih kola ugledaše Jošafata, rekoše: “To je izraelski kralj!” I krenuše na nj da udare. Ali Jošafat povika za pomoć te mu Jahve pomože i odvrati ih od njega."},{"v":32,"t":"Kad zapovjednici bojnih kola vidješe da to nije izraelski kralj, okrenuše se od njega."},{"v":33,"t":"Jedan nasumce odape i ustrijeli izraelskoga kralja između nabora na pojasu i oklopa. Kralj reče vozaču: “Potegni uzdu i izvedi me iz boja jer sam ranjen.”"},{"v":34,"t":"Boj je onoga dana bio sve žešći, ali se izraelski kralj držao uspravno na bojnim kolima prema Aramejcima sve do večeri. Umro je o zalasku sunca."}]},"19":{"hr":[{"v":1,"t":"Kad se judejski kralj Jošafat sretno vrati kući u Jeruzalem,"},{"v":2,"t":"iziđe preda nj Hananijev sin vidjelac Jehu i reče kralju Jošafatu: “Zar da pomažeš bezbožniku i da ljubiš Jahvine mrzitelje? Zato i udara na te srdžba Jahvina."},{"v":3,"t":"Ipak se našlo nešto dobro u tebe: uklonio si ašere iz zemlje i pregnuo svim srcem da tražiš Jahvu!”"},{"v":4,"t":"Od tada je Jošafat živio u Jeruzalemu, opet zalazio među narod od Beer Šebe do Efrajimske gore i obraćao ga Jahvi, Bogu njegovih otaca."},{"v":5,"t":"Postavi suce u zemlji u svim tvrdim judejskim gradovima, u svakome gradu."},{"v":6,"t":"I reče im: “Gledajte što radite, jer ne sudite u ime čovjeka nego u ime Jahve. On je s vama dok sudite."},{"v":7,"t":"Sada, dakle, neka bude Jahvin strah nad vama; pazite i savjesno radite, jer u Jahve, Boga našega, nema nepravde ni osobne pristranosti, niti on prima mita.”"},{"v":8,"t":"Jošafat postavi levite, svećenike i poglavare izraelskih obitelji u Jeruzalemu da izriču Jahvine sudove i da presuđuju u sporovima. Oni su živjeli u Jeruzalemu"},{"v":9,"t":"i on im dade naputke: “Radite u Jahvinu strahu vjerno i iskrena srca."},{"v":10,"t":"Kakav god spor iziđe pred vas od vaše braće što žive u gradovima: bilo da su posrijedi krvna osveta, Zakon, zapovijedi, uredbe ili običaji, valja sve da im rastumačite, kako ne bi sagriješili Jahvi i kako se njegova srdžba ne bi oborila na vas i na vašu braću. Tako radite pa nećete sagriješiti."},{"v":11,"t":"I evo, svećenički će poglavar Amarja biti nad vama u svim Jahvinim poslovima, a Jišmaelov sin Zebadja, nadstojnik Judina doma, u svim kraljevskim poslovima. Leviti će vam služiti kao pisari. Budite jaki, i na posao! Jahve će biti s onim tko je dobar.”"}]},"20":{"hr":[{"v":1,"t":"Poslije toga Moabovi i Amonovi sinovi, a s njima i neki od Meunjana, zaratiše na Jošafata."},{"v":2,"t":"Ali Jošafat dobi ovu vijest: “Dolazi na te veliko mnoštvo s one strane mora, iz Edoma; i eno ga u Haseson Tamaru, to jest u En Gediju.”"},{"v":3,"t":"Jošafat se uplaši i stade tražiti Jahvu te oglasi post po svoj Judeji."},{"v":4,"t":"Skupili se Judejci da traže Jahvu: dolazili iz svih judejskih gradova da ga traže."},{"v":5,"t":"Tada Jošafat ustade u judejskom zboru u Jeruzalemu, u Domu Jahvinu, pred novim predvorjem"},{"v":6,"t":"i reče: “Jahve, Bože otaca naših, ti si Bog na nebu i vladaš nad svim krivobožačkim kraljevstvima. U tvojoj je ruci takva sila i jakost da se nitko ne može održati pred tobom."},{"v":7,"t":"Ti si, o Bože naš, istjerao stanovnike ove zemlje pred svojim izraelskim narodom i dao je zasvagda potomstvu svoga prijatelja Abrahama;"},{"v":8,"t":"i nastanili su se u njoj i sagradili u njoj Svetište tvojem Imenu govoreći:"},{"v":9,"t":"'Kad navali na nas kakvo zlo, osvetni mač ili kuga, ili glad, te kad stanemo pred ovim Domom i pred tobom, jer je tvoje Ime u ovom Domu, i zavapimo k tebi iz svoje nevolje, usliši nas i spasi.'"},{"v":10,"t":"Sada, evo, Amonovi i Moabovi sinovi, i oni iz Seirske gore, preko kojih nisi dao Izraelu da prođe kad je dolazio iz zemlje egipatske, nego ih je obišao i nije ih zatro -"},{"v":11,"t":"sada, dakle, oni nama uzvraćaju zlom, došavši da nas otjeraju s baštine koju si nam ti dao."},{"v":12,"t":"O Bože naš, zar im nećeš suditi? Jer u nas nema sile prema tome velikom mnoštvu koje dolazi na nas niti mi znamo što da radimo, nego su nam oči uprte u te.”"},{"v":13,"t":"Svi su Judejci stajali pred Jahvom, s malom djecom, sa ženama i sinovima."},{"v":14,"t":"Tada siđe Jahvin duh usred zbora na Jahaziela, sina Zaharije, sina Benaje, sina Jeiela, sina Matanijina - levita od Asafovih sinova."},{"v":15,"t":"On reče: “Pozorno slušajte, svi Judejci, Jeruzalemci i ti, kralju Jošafate! Ovako vam govori Jahve: 'Ne bojte se i ne plašite se toga velikog mnoštva, jer ovo nije vaš rat, nego Božji."},{"v":16,"t":"Sutra siđite na njih; oni će se penjati uz Hasiški uspon, a vi ćete ih sresti nakraj doline prema Jeruelskoj pustinji."},{"v":17,"t":"Ne treba da se bijete; postavite se, stojte pa gledajte kako će vam pomoći Jahve. Oj Judo i Jeruzaleme, ne bojte se i ne plašite se; sutra iziđite pred njih, i Jahve će biti s vama!'”"},{"v":18,"t":"Tada Jošafat pade ničice na zemlju i svi Judejci i Jeruzalemci padoše pred Jahvom da mu se poklone."},{"v":19,"t":"Potom leviti od Kehatovih sinova i od Korahovih sinova ustadoše i počeše hvaliti na sav glas Jahvu, Boga Izraelova."},{"v":20,"t":"Uranivši ujutro, krenuše prema pustinji Tekoi; kad su izlazili, stade Jošafat i reče: “Čujte me, oj Judejci i Jeruzalemci, pouzdajte se u Jahvu svoga Boga i održat ćete se; pouzdajte se u njegove proroke i budite sretni!”"},{"v":21,"t":"Potom se posavjetova s narodom i postavi Jahvine pjevače i hvalitelje koji će u svetom ruhu ići pred naoružanim četama i pjevati: “Slavite Jahvu jer je vječna ljubav njegova!”"},{"v":22,"t":"Kad počeše klicati i pjevati pjesmu pohvalnicu, Jahve podiže zasjedu na Amonce, Moapce i na one iz Seirske gore koji su došli na Judu te biše razbijeni."},{"v":23,"t":"Jer su Amonovi sinovi i Moapci ustali na one iz Seirske gore da ih zatru i unište; a kad su svršili s onima iz Seira, stadoše udarati jedan na drugoga te se poklaše."},{"v":24,"t":"Kad Judejci dođoše do stražare prema pustinji i obazreše se na mnoštvo, a ono gle, mrtva tjelesa leže po zemlji; nitko se nije spasio."},{"v":25,"t":"Tada dođe Jošafat s narodom da pokupi plijen i nađoše ga mnogo: svakoga blaga, odjeće i dragocjenih predmeta; naplijenili su toliko da više nisu mogli nositi; tri su dana pljačkali plijen jer ga je bilo mnogo."},{"v":26,"t":"Četvrti se dan sakupiše u Dolini blagoslova: ondje su hvalili Jahvu, pa se zato ono mjesto prozvalo Emek Beraka, Dolina blagoslova, do danas."},{"v":27,"t":"Potom se okrenuše svi Judejci i Jeruzalemci, s Jošafatom na čelu, da se vrate u Jeruzalem u veselju, jer ih je Jahve razveselio nad njihovim neprijateljima."},{"v":28,"t":"Došli su u Jeruzalem s harfama, citrama i trubama u Dom Jahvin."},{"v":29,"t":"A strah Božji ušao je u sva zemaljska kraljevstva kad su čula da je Jahve zavojštio na Izraelove neprijatelje."},{"v":30,"t":"Tako je počinulo Jošafatovo kraljevstvo, jer mu je Bog dao mir odasvud uokolo."},{"v":31,"t":"Jošafat je kraljevao nad Judejcima. Bilo mu je trideset i pet godina kad se zakraljio; kraljevao je dvadeset i pet godina u Jeruzalemu; mati mu se zvala Azuba, a bila je kći Šilhijeva."},{"v":32,"t":"Išao je putem oca Ase ne skrećući s njega nego čineći što je pravo u Jahvinim očima."},{"v":33,"t":"Samo, uzvišice nisu bile uklonjene, jer narod još nije bio upravio svoje srce Bogu otaca."},{"v":34,"t":"Ostala Jošafatova djela, od prvih do posljednjih, zapisana su u povijesti Hananijeva sina Jehua i uvrštena su u Knjigu o izraelskim kraljevima."},{"v":35,"t":"Poslije toga udružio se judejski kralj Jošafat s izraelskim kraljem Ahazjom, koji je bezbožno radio."},{"v":36,"t":"Udružio se s njim zato da naprave lađe i da odu u Taršiš; napravili su lađe u Esjon Geberu."},{"v":37,"t":"Dodavahuov sin Eliezer iz Mareše prorekao je protiv Jošafata: “Budući da si se udružio s Ahazjom, Jahve će razoriti tvoja djela.” Lađe su se razbile i nisu mogle otploviti u Taršiš."}]},"21":{"hr":[{"v":1,"t":"Jošafat počinu kraj svojih otaca i bi sahranjen uz njih u Davidovu gradu. Na njegovo se mjesto zakraljio sin mu Joram."},{"v":2,"t":"Joram je imao šestoricu braće, Jošafatovih sinova: Azarju, Jehiela, Zahariju, Azarju, Mihaela i Šefatju. Svi su oni bili sinovi izraelskog kralja Jošafata."},{"v":3,"t":"Otac im je dao mnoge darove u srebru, zlatu i dragocjenostima, s utvrđenim gradovima u Judi; kraljevstvo je dao Joramu jer je bio prvenac."},{"v":4,"t":"Stupivši na očevo prijestolje i utvrdiv se, Joram pobi svu braću mačem, pa i neke izraelske knezove."},{"v":5,"t":"Joramu su bile trideset i dvije godine kad se zakraljio, a kraljevao je osam godina u Jeruzalemu."},{"v":6,"t":"Živio je poput izraelskih kraljeva, kao i dom Ahabov, jer mu je kći Ahabova bila žena; radio je što je zlo u Jahvinim očima."},{"v":7,"t":"Ipak Jahve ne htjede razoriti kuće Davidu zbog Saveza što ga sklopi s njim i zato što mu obeća da će dati svjetiljku njemu i njegovim sinovima zauvijek."},{"v":8,"t":"U njegovo se vrijeme Edomci odmetnuše ispod judejske vlasti i postaviše sebi kralja."},{"v":9,"t":"Zato Joram pođe sa svojim vojskovođama i sa svim bojnim kolima. Diže se noću i pobi Edomce koji bijahu opkolili njega i zapovjednike bojnih kola."},{"v":10,"t":"Ipak su se Edomci oslobodili ispod judejske vlasti sve do danas. U isto se doba odmetnu i Libna da ne bude pod njegovom vlašću, jer je on ostavio Jahvu, Boga svojih otaca."},{"v":11,"t":"Još je i uzvišice napravio po judejskim gorama, naveo na blud Jeruzalemce i zaveo Judejce."},{"v":12,"t":"Tada mu od proroka Ilije stiže pismo: “Ovako veli Jahve, Bog tvoga oca Davida: 'Kako nisi išao putovima oca Jošafata, ni putovima judejskoga kralja Ase,"},{"v":13,"t":"nego si išao putovima izraelskih kraljeva i naveo na blud Judejce i Jeruzalemce, kao što je učinio dom Ahabov, a uz to si poubijao vlastitu braću, svoju obitelj, koji bjehu bolji od tebe:"},{"v":14,"t":"evo, Jahve će svaliti veliku nesreću na tvoj narod, na tvoje sinove, tvoje žene, na sve tvoje imanje."},{"v":15,"t":"Oboljet ćeš od mnogih bolesti: od bolesti u crijevima, tako da će ti crijeva izaći od bolesti koja će trajati dane i dane.'”"},{"v":16,"t":"Jahve podiže na Jorama srdžbu Filistejaca i Arapa koji žive kraj Etiopljana."},{"v":17,"t":"Oni napadoše Judeju i osvojiše je, porobiše sve blago što se našlo u kraljevu dvoru, pa i njegove sinove i njegove žene, tako da nije ostao nitko, osim najmlađega sina, Joahaza."},{"v":18,"t":"Poslije svega toga udari ga Jahve neizlječivom crijevnom bolešću."},{"v":19,"t":"Ona je trajala dane i dane, a kad su se navršile dvije godine, izašla su mu crijeva s bolešću te je umro u strašnim mukama. Narod mu nije priredio mirisna paljenja, kao što je palio njegovim ocima."},{"v":20,"t":"Bile su mu trideset i dvije godine kad se zakraljio, a osam je godina kraljevao u Jeruzalemu. Preminuo je, a nitko nije požalio za njim; i sahraniše ga u Davidovu gradu, ali ne u kraljevskoj grobnici."}]},"22":{"hr":[{"v":1,"t":"Jeruzalemci zakraljiše na njegovo mjesto najmlađeg mu sina, Ahazju, jer sve starije bijaše poubijala četa koja je s Arapima navalila na tabor; tako se zakraljio Ahazja, sin judejskoga kralja Jorama."},{"v":2,"t":"Bile su mu četrdeset i dvije godine kad se zakraljio. Kraljevao je jednu godinu u Jeruzalemu. Materi mu je bilo ime Atalija, Omrijeva kći."},{"v":3,"t":"I on je išao putovima doma Ahabova, jer ga mati zlo svjetovaše."},{"v":4,"t":"Činio je što je zlo u Jahvinim očima, kao dom Ahabov, jer mu baš oni bijahu savjetnici poslije očeve smrti, na njegovu propast."},{"v":5,"t":"Po njihovu je savjetu pošao s Joramom, sinom izraelskoga kralja Ahaba, u boj na aramejskoga kralja Hazaela u Ramot Gilead. Ali su Aramejci porazili Jorama."},{"v":6,"t":"On se vratio da se liječi u Jizreelu od rana što mu ih zadadoše u Rami kad se borio s aramejskim kraljem Hazaelom. Joramov sin Ahazja, judejski kralj, sišao je u Jizreel da posjeti Ahabova sina Jorama jer se Joram razbolio."},{"v":7,"t":"Ali Bog učini da taj posjet Joramu bude na propast Ahazji. Došavši, izišao je s Joramom na Nimšijeva sina Jehua, koga je Jahve pomazao da iskorijeni Ahabovu kuću."},{"v":8,"t":"Dok je izvršavao osvetu nad Ahabovom kućom, Jehu zateče judejske knezove i sinove Ahazjine braće koji su posluživali Ahazju i pobi ih,"},{"v":9,"t":"a onda krenu u potragu za Ahazjom. Uhvatili su ga dok se krio u Samariji, doveli ga k Jehuu, koji ga smaknu. Ukopali su ga, jer su rekli: “Sin je onoga Jošafata koji je tražio Jahvu svim srcem.” Tako ne ostade nitko od Ahazjine kuće koji bi imao snage da bude kralj."},{"v":10,"t":"Zato Ahazjina mati Atalija, vidjevši gdje joj sin poginu, ustade i posmica sav kraljevski rod Judina plemena."},{"v":11,"t":"Ali kraljeva kći Jošeba uze Ahazjina sina Joaša; ukravši ga između kraljevih sinova koje su ubijali, metnu ga s dojiljom u ložnicu. Tako ga je Jošeba, kći kralja Jorama, žena svećenika Jojade, sakrila od Atalije, jer je bila Ahazjina sestra, te nije bio pogubljen."},{"v":12,"t":"Bio je sakriven s njima u Domu Božjem šest godina, sve dok je zemljom vladala Atalija."}]},"23":{"hr":[{"v":1,"t":"Sedme se godine Jojada ojunači i poče tražiti satnike: Jerohamova sina Azarju, Johananova sina Jišmaela, Obedova sina Azarju, Adajina sina Maaseju, Zikrijeva sina Elišafata, i sklopi s njima savez."},{"v":2,"t":"Počeše obilaziti po Judeji i skupiše levite iz svih judejskih gradova i obiteljske glavare u Izraelu te dođoše u Jeruzalem."},{"v":3,"t":"Sav zbor sklopi savez s kraljem u Domu Božjem. Jojada im reče: “Gle, kraljev će sin kraljevati kao što je obećao Jahve za Davidove sinove."},{"v":4,"t":"Evo što valja da učinite: trećina vas koji subotom ulazite u službu, i svećenici i leviti, neka budu vratari na pragovima;"},{"v":5,"t":"trećina neka bude u kraljevskom dvoru, trećina na Jesodskim vratima, sav narod u predvorjima Doma Jahvina."},{"v":6,"t":"Nitko neka ne ulazi u Dom Jahvin, osim svećenika i levita koji poslužuju; oni neka ulaze jer su posvećeni. Sav narod neka se drži Jahvine naredbe."},{"v":7,"t":"Leviti neka okruže kralja, svaki s oružjem u ruci, i tko god pokuša ući u Dom neka bude pogubljen. Budite uz kralja kamo god pođe ili izađe.”"},{"v":8,"t":"Leviti i sav judejski narod učinili su sve onako kako je naredio svećenik Jojada. Svaki je uzeo svoje ljude koji subotom ulaze u službu s onima koji subotom izlaze. Jer svećenik Jojada nije otpustio redova."},{"v":9,"t":"Svećenik Jojada dade satnicima koplja, štitove i oklope kralja Davida što su bili u Božjemu Domu."},{"v":10,"t":"Postavio je sav narod, svakoga s kopljem u ruci, od južne do sjeverne strane Doma, prema žrtveniku i prema Domu oko kralja unaokolo."},{"v":11,"t":"Tada izvedoše kraljeva sina, staviše mu krunu na glavu, dadoše mu Svjedočanstvo i pomazaše ga za kralja. Tada Jojada i njegovi sinovi povikaše: “Živio kralj!”"},{"v":12,"t":"Kad Atalija ču viku naroda koji se skupio i hvalio kralja, dođe k narodu u Jahvin Dom."},{"v":13,"t":"Pogleda bolje, kad gle, kralj stoji na svojem mjestu na ulazu, a pred kraljem zapovjednici i svirači; sav puk kliče od radosti i trubi u trube, pjevači pjevaju uz glazbala i predvode hvalospjeve. Tad Atalija razdrije haljine i povika: “Izdaja, izdaja!”"},{"v":14,"t":"Svećenik Jojada naredi satnicima i vojnim zapovjednicima: “Izvedite je kroz redove napolje i tko krene za njom pogubite ga mačem!” Još je svećenik dodao: “Nemojte je smaknuti u Jahvinu Domu!”"},{"v":15,"t":"Staviše ruke na nju i kad je kroz Konjska vrata stigla do kraljevskoga dvora, ondje je pogubiše."},{"v":16,"t":"Tada Jojada sklopi savez između Jahve, naroda i kralja da narod bude Jahvin."},{"v":17,"t":"Potom sav narod otiđe u Baalov hram, razori ga skupa sa žrtvenicima i polomi likove; Baalova svećenika Matana ubiše pred žrtvenicima."},{"v":18,"t":"Zatim Jojada postavi straže kod Jahvina Doma pod nadzorom svećenika i levita, koje David bijaše porazdijelio za službu u Jahvinu Domu da bi Jahvi prinosili paljenice, kao što je pisano u Mojsijevu Zakonu, s veseljem i s pjesmama, kako uredi David."},{"v":19,"t":"Postavio je i vratare na vratima Jahvina Doma da ne bi ulazio čovjek nečist od bilo čega."},{"v":20,"t":"Uzevši satnike, odličnike i uglednike u narodu i sav puk, izveo je kralja iz Jahvina Doma, a onda su ušli kroz gornja vrata u kraljevski dvor i posadili kralja na kraljevsko prijestolje."},{"v":21,"t":"Sav se puk veselio, a grad se umirio, jer su Ataliju ubili mačem."}]},"24":{"hr":[{"v":1,"t":"Joašu je bilo sedam godina kad se zakraljio, a kraljevao je četrdeset godina u Jeruzalemu. Materi mu je bilo ime Sibja iz Beer Šebe."},{"v":2,"t":"Joaš je činio što je pravo u Jahvinim očima dok je bio živ svećenik Jojada."},{"v":3,"t":"Jojada ga je oženio dvjema ženama i on je s njima imao sinova i kćeri."},{"v":4,"t":"Poslije toga nakanio je u srcu obnoviti Jahvin Dom."},{"v":5,"t":"Skupivši svećenike i levite, reče im: “Zađite po judejskim gradovima i kupite od svih Izraelaca novaca da se obnovi Dom vašega Boga, od godine do godine, a vi pohitite s tim poslom.” Ali se levitima nije htjelo."},{"v":6,"t":"Zato kralj pozva poglavara Jojadu i reče mu: “Zašto ne tražiš od levita da donose iz Judeje i iz Jeruzalema porez koji je odredio Jahvin sluga Mojsije i Izraelov zbor za Šator svjedočanstva?"},{"v":7,"t":"Atalija i njeni sinovi bijahu poharali Božji Dom, i sve stvari što su bile posvećene Jahvinu Domu upotrijebili su za baale.”"},{"v":8,"t":"Potom kralj zapovjedi da se napravi kovčeg i stavi izvana na vrata Jahvina Doma."},{"v":9,"t":"Oglasiše po Judi i Jeruzalemu da se donosi Jahvi porez što ga bijaše odredio Božji sluga Mojsije Izraelu u pustinji."},{"v":10,"t":"Obradovaše se svi knezovi i sav narod i počeše donositi i bacati u kovčeg dok se nije napunio."},{"v":11,"t":"Leviti bi donosili kovčeg kraljevskom nadgledništvu, i kad bi se vidjelo da ima mnogo novaca, dolazio je kraljev tajnik i povjerenik svećeničkog poglavara te bi ispraznili kovčeg. Onda su ga opet odnosili i stavljali na njegovo mjesto. Tako su činili svaki dan i sabrali mnogo novca."},{"v":12,"t":"Onda su ga kralj i Jojada davali poslovođama nad poslom oko Jahvina Doma, a oni su za plaću unajmljivali klesare i drvodjelce da se obnovi Jahvin Dom, pa kovače i mjedare da se popravi Jahvin Dom."},{"v":13,"t":"Poslovođe su poslovale i popravljanje je napredovalo pod njihovom upravom; vratili su Božji Dom u red i obnovili ga."},{"v":14,"t":"A kad su sve svršili, donijeli su pred kralja i Jojadu novce što su ostali; od toga su napravili posuđe za Jahvin Dom, posuđe za posluživanje, za paljenje, plitice i druge zlatne i srebrne predmete. Paljenice su se prinosile u Jahvinu Domu bez prestanka dok je god živio Jojada."},{"v":15,"t":"Onda je Jojada, ostarjevši i nasitivši se života, umro u sto i tridesetoj godini."},{"v":16,"t":"Sahranili su ga u Davidovu gradu kod kraljeva, jer je činio dobro u Izraelu i prema Bogu i njegovu Domu."},{"v":17,"t":"Poslije Jojadine smrti došli su Judini knezovi i poklonili se kralju. Tada ih kralj poče slušati."},{"v":18,"t":"Judejci bijahu ostavili Jahvu, Boga otaca, i stali služiti ašerama i likovima; došla je Božja srdžba na Judejce i na Jeruzalem za tu krivicu."},{"v":19,"t":"Slao im je Bog proroke da ih obrate k Jahvi, oni su ih opominjali, ali oni nisu htjeli slušati."},{"v":20,"t":"Tada Božji duh napuni Jojadina sina, svećenika Zahariju, koji, stavši poviše naroda, reče: “Ovako veli Bog: 'Zašto kršite Jahvine zapovijedi? Zašto nećete da budete sretni? Kako ste vi ostavili Jahvu, i on će vas ostaviti.'”"},{"v":21,"t":"Ali su se oni pobunili protiv njega i zasuli ga kamenjem po kraljevoj zapovijedi u predvorju Jahvina Doma."},{"v":22,"t":"Ni kralj Joaš ne sjeti se ljubavi koju mu učini otac Jojada, nego mu ubi sina; a on je umirući rekao: “Jahve neka vidi i osveti!”"},{"v":23,"t":"Kad je prošla godina dana, diže se na nj aramejska vojska i, navalivši na Judu i Jeruzalem, pobi sve knezove u narodu i posla sav plijen kralju u Damask."},{"v":24,"t":"Iako je aramejska vojska bila malena po ljudstvu, ipak joj je Jahve predao u ruke vrlo brojnu vojsku, jer ostaviše Jahvu, Boga svojih otaca. Tako su se Aramejci na Joašu osvetili."},{"v":25,"t":"Kad su otišli od njega, ostaviv ga u teškim bolestima, pobuniše se protiv njega njegovi časnici jer bijaše ubio sina svećenika Jojade, pa i oni njega ubiše na postelji te je poginuo; sahranili su ga u Davidovu gradu, ali ga nisu ukopali u kraljevskoj grobnici."},{"v":26,"t":"Evo onih što se urotiše protiv njega: Zabad, sin Amonke Šimeate, i Jozabad, sin Moapke Šimrite."},{"v":27,"t":"A o njegovim sinovima i o velikim proroštvima protiv njega, o obnavljanju Doma Božjega, sve je zapisano u tumačenju Knjige o kraljevima. Na njegovo se mjesto zakraljio sin mu Amasja."}]},"25":{"hr":[{"v":1,"t":"Amasji je bilo dvadeset i pet godina kad se zakraljio; kraljevao je dvadeset i devet godina u Jeruzalemu. Mati mu se zvala Joadana i bila je iz Jeruzalema."},{"v":2,"t":"Činio je što je pravo u Jahvinim očima, ali ne svim srcem."},{"v":3,"t":"Kad je učvrstio kraljevstvo, pogubio je časnike koji su ubili kralja, njegova oca."},{"v":4,"t":"Ali im sinova nije pogubio, prema onome što je napisano u knjizi Zakona Mojsijeva, gdje Jahve zapovijeda: “Neka se očevi ne pogubljuju za sinove, ni sinovi za očeve, nego svatko neka gine za svoj grijeh.”"},{"v":5,"t":"Potom Amasja skupi Judejce i svega Judu i Benjamina, razvrsta ih prema obiteljima, tisućnicima i satnicima. Pošto popisa od dvadeset godina naviše, nađe trista tisuća izabranih momaka za vojsku, vičnih koplju i štitu."},{"v":6,"t":"Među Izraelcima najmi sto tisuća hrabrih junaka za sto srebrnih talenata."},{"v":7,"t":"Ali k njemu dođe čovjek Božji i reče: “Kralju, neka ne ide s tobom izraelska vojska, jer Jahve nije s Izraelcima ni s Efrajimovim sinovima,"},{"v":8,"t":"nego idi ti sam, ponesi se junački u boju; inače će te oboriti Bog pred neprijateljem, jer Bog može pomoći i oboriti.”"},{"v":9,"t":"Tada Amasja upita čovjeka Božjeg: “A što će biti od sto talenata koje sam dao izraelskim četama?” Božji čovjek odgovori: “Jahve ima da ti dade više od toga.”"},{"v":10,"t":"Tada Amasja odvoji čete koje mu bijahu došle od Efrajima, da se vrate u svoje mjesto. Ali se vojnici razgnjeviše na Judejce i vratiše se u svoje mjesto plamteći od srdžbe."},{"v":11,"t":"A Amasja, ohrabriv se, povede narod, ode u Slanu dolinu i pobi deset tisuća seirskih sinova."},{"v":12,"t":"Judini su sinovi zarobili deset tisuća živih, odveli ih na vrh hridi te ih pobacali, tako da se svi razmrskaše."},{"v":13,"t":"Četa koju je Amasja poslao natrag da ne ide s njima u boj harala je po judejskim gradovima od Samarije pa do Bet Horona i pobila u njima tri tisuće ljudi i naplijenila silan plijen."},{"v":14,"t":"Poslije toga, kad se Amasja vratio razbivši Edomce, donio je bogove seirskih sinova, postavio ih sebi za bogove i počeo im se klanjati i kaditi im."},{"v":15,"t":"Tada se Jahve razgnjevi na Amasju i posla k njemu proroka koji ga upita: “Zašto tražiš bogove toga naroda koji nisu izbavili svoga naroda iz tvoje ruke?”"},{"v":16,"t":"Dok je on to govorio, kralj ga upita: “Jesi li postavljen kralju za savjetnika? Prestani! Zašto da te pogube?” Tada prorok ušutje, ali nadoda: “Znam da te Bog odlučio uništiti kad to činiš a ne slušaš mojega savjeta.”"},{"v":17,"t":"Tada judejski kralj Amasja smisli i poruči izraelskom kralju Joašu, sinu Jehuova sina Joahaza: “Dođi da se ogledamo!”"},{"v":18,"t":"A izraelski kralj Joaš odvrati judejskom kralju Amasji: “Libanonski je trn jedanput poslao glasnike k libanonskom cedru i poručio: 'Daj kćer mome sinu za ženu', ali su divlje zvijeri libanonske prošle i trn izgazile."},{"v":19,"t":"Potukao si Edomce, pa ti se srce uzobijestilo i tražiš slavu. Radije ostani kod kuće. Zašto izazivaš zlo i hoćeš da padneš i ti i svi Judejci s tobom?”"},{"v":20,"t":"Ali Amasja ne posluša, jer tako bijaše odredio Bog, da ih preda u ruke Joašu zato što su pristali uz edomske bogove."},{"v":21,"t":"Izađe izraelski kralj Joaš te se ogledaše u boju on i judejski kralj Amasja u Bet Šemešu u Judeji."},{"v":22,"t":"Izraelci poraziše Judejce i oni pobjegoše pod svoj šator."},{"v":23,"t":"Izraelski kralj Joaš uhvati u Bet Šemešu judejskog kralja Amasju, sina Joaševa, sina Joahazova, i odvede ga u Jeruzalem; onda sruši jeruzalemski zid od Efrajimovih vrata do Ugaonih vrata, u dužini od četiri stotine lakata."},{"v":24,"t":"Uzevši sve zlato, srebro i posuđe što se nalazilo u Domu Božjem kod Obed Edoma i u riznici kraljevskog dvora, povrh toga i taoce, vrati se u Samariju."},{"v":25,"t":"Judejski je kralj Amasja, Joašev sin, živio još petnaest godina poslije smrti izraelskoga kralja Joaša, Joahazova sina."},{"v":26,"t":"Ostala Amasjina djela, od prvih do posljednjih, zapisana su u Knjizi o judejskim i izraelskim kraljevima."},{"v":27,"t":"Otkako je Amasja ostavio Jahvu, kovala se protiv njega urota u Jeruzalemu. Iako je pobjegao u Lakiš, poslaše za njim u Lakiš ljude koji ga ondje ubiše."},{"v":28,"t":"Odande su ga prenijeli na konjima i sahranili kraj njegovih otaca u Judinu gradu."}]},"26":{"hr":[{"v":1,"t":"Tada sav judejski narod uze Uziju, komu bijaše šesnaest godina, i zakraljiše ga namjesto njegova oca Amasje."},{"v":2,"t":"On je opet sagradio Elat vrativši ga Judeji, pošto je kralj počinuo kod svojih otaca."},{"v":3,"t":"Uziji bijaše šesnaest godina kad se zakraljio, a kraljevao je pedeset i dvije godine u Jeruzalemu. Mati mu se zvala Jekolija, a bila je iz Jeruzalema."},{"v":4,"t":"Činio je što je pravo u Jahvinim očima, sasvim kao i njegov otac Amasja."},{"v":5,"t":"Tražio je Boga za života Zaharije, koji ga je učio Božjem strahu; dokle je god tražio Jahvu, davao mu je Bog sreću."},{"v":6,"t":"On je izišao i zavojštio na Filistejce, srušio zid Gata, zid Jabne i zid Ašdoda; sagradio je mjesta po Ašdodu i Filisteji."},{"v":7,"t":"Bog mu je pomogao protiv Filistejaca i protiv Arapa, koji su živjeli u Gur Baalu, i protiv Meunjana."},{"v":8,"t":"Amonci su davali danak Uziji, a njegov se glas pronio do Egipta, jer se bijaše vrlo osilio."},{"v":9,"t":"Uzija je sagradio kule u Jeruzalemu kod Ugaonih vrata, kod Dolinskih vrata i na uglu te ih utvrdio."},{"v":10,"t":"Sagradio je i u pustinji kule i iskopao mnogo studenaca, jer je imao mnogo stoke i u Šefeli i po Ravnici, ratara i vinogradara u gorama i vrtovima, jer je volio poljodjelstvo."},{"v":11,"t":"Uzija je imao vojsku vještu boju koja je išla u rat u četama po broju kako ih je izbrojio tajnik Jeiel i nadzornik Maasja pod upravom Hananije, jednoga od kraljevih knezova."},{"v":12,"t":"Svega je na broj bilo, obiteljskih glavara, hrabrih junaka, dvije tisuće i šest stotina."},{"v":13,"t":"Pod njihovom je upravom bilo silne vojske trista sedam tisuća i pet stotina boju vičnih ratnika da pomažu kralju protiv neprijatelja."},{"v":14,"t":"Uzija je pripravio svoj vojsci štitove, koplja, kacige, oklope, lukove i kamenje za praćke."},{"v":15,"t":"Napravio je u Jeruzalemu vješto smišljene bojne sprave, iznašašće nekoga graditelja, da stoje na kulama i na kruništima, da bacaju strijele i veliko kamenje; pronio mu se glas nadaleko jer je uživao čudesnu pomoć sve dok se nije osilio."},{"v":16,"t":"Ali kad se osilio, uzobijestilo mu se srce dotle da se pokvario te se iznevjerio Jahvi, svome Bogu, jer je ušao u Jahvin Hekal i počeo prinositi kad na kadionom žrtveniku."},{"v":17,"t":"Ali je za njim ušao svećenik Azarja i s njim osamdeset Jahvinih svećenika, čestitih ljudi."},{"v":18,"t":"Oni ustadoše na kralja Uziju govoreći: “Nije tvoje, Uzijo, da kadiš Jahvi, nego je to dužnost svećenika, Aronovih sinova, koji su posvećeni da kade. Izlazi iz Svetišta! Iznevjerio si se. I ne služi ti na čast pred Bogom Jahvom!”"},{"v":19,"t":"Tada se Uzija rasrdi držeći u ruci kadionicu da kadi; kad se rasrdio na svećenike, izbi mu guba na čelu pred svećenicima u Domu Jahvinu kraj kadionog žrtvenika."},{"v":20,"t":"Kad ga svećenički poglavar Azarja i svi svećenici izbližega pogledaše, a ono, gle, izbila mu guba na čelu; brže ga otjeraše odande, a i on sam pohitje da iziđe jer ga Jahve bijaše udario."},{"v":21,"t":"Kralj Uzija ostade gubav do smrti i stanovaše u odvojenoj kući, jer bijaše odstranjen od Doma Jahvina; njegov je sin Jotam bio upravitelj kraljevskoga dvora i sudio je puku zemlje."},{"v":22,"t":"Ostala Uzijina djela, od prvih do posljednjih, opisao je Amosov sin, prorok Izaija."},{"v":23,"t":"Uzija je počinuo i sahranili su ga kraj njegovih otaca na polju kod kraljevske grobnice, rekavši: “Gubav je.” Na njegovo se mjesto zakraljio sin mu Jotam."}]},"27":{"hr":[{"v":1,"t":"Jotamu je bilo dvadeset i pet godina kad se zakraljio, a kraljevao je šesnaest godina u Jeruzalemu. Materi mu je bilo ime Jeruša, Sadokova kći."},{"v":2,"t":"Činio je što je pravo u Jahvinim očima, sasvim kao otac mu Uzija; samo što nije ušao u Jahvin Hekal. Narod je i dalje bio pokvaren."},{"v":3,"t":"Sagradio je Gornja vrata Doma Jahvina; i na Ofelskom zidu mnogo je gradio."},{"v":4,"t":"Podigao je i gradove po Judejskoj gori, a u šumama dvorove i kule."},{"v":5,"t":"Vojevao je s kraljem Amonovih sinova i pobijedio ih. Amonovi su mu sinovi dali one godine sto srebrnih talenata i deset tisuća kora pšenice i deset tisuća kora ječma. Toliko su mu Amonovi sinovi priložili i druge i treće godine."},{"v":6,"t":"Tako se Jotam utvrdio, jer je uredio svoj život pred Jahvom, svojim Bogom."},{"v":7,"t":"Ostala su Jotamova djela i svi njegovi ratovi i putovi zapisani u Knjizi o izraelskim i judejskim kraljevima."},{"v":8,"t":"Bilo mu je dvadeset i pet godina kad se zakraljio. Kraljevao je šesnaest godina u Jeruzalemu."},{"v":9,"t":"Tada Jotam počinu kod otaca i sahraniše ga u Davidovu gradu. Na njegovo se mjesto zakralji sin mu Ahaz."}]},"28":{"hr":[{"v":1,"t":"Ahazu je bilo dvadeset godina kad se zakraljio, a kraljevao je šesnaest godina u Jeruzalemu, ali nije činio što je pravo u Jahvinim očima kao što je činio njegov otac David."},{"v":2,"t":"Živio je poput izraelskih kraljeva, pa je i likove salio baalima."},{"v":3,"t":"Sam je prinosio kad u dolini Hinomova sina i proveo vlastite sinove kroz oganj, po gnusnom običaju krivobožačkih naroda što ih je Jahve protjerao pred Izraelovim sinovima."},{"v":4,"t":"Prinosio je žrtve i kadio po uzvišicama i brežuljcima i pod svakim zelenim drvetom."},{"v":5,"t":"Zato ga Jahve, njegov Bog, predade u ruke aramejskom kralju te ga on potuče, zarobi mu veliko mnoštvo ljudi i odvede ih u Damask. Još je bio predan u ruke izraelskom kralju koji ga je hametice porazio."},{"v":6,"t":"Remalijin je sin Pekah pobio među Judejcima sto dvadeset tisuća hrabrih junaka u jedan dan, jer su bili ostavili Jahvu, Boga svojih otaca."},{"v":7,"t":"A junak od Efrajimova plemena Zikri pogubio je kraljeva sina Maaseju i dvorskoga upravitelja Azrikama i Elkanu, drugoga do kralja."},{"v":8,"t":"Izraelovi su sinovi zarobili od svoje braće dvjesta tisuća žena, sinova i kćeri, a zadobili su i silan plijen od njih i odnijeli ga u Samariju."},{"v":9,"t":"Ondje bijaše Jahvin prorok po imenu Oded; izašao on pred vojsku što je išla u Samariju i rekao: “Gle, Jahve, Bog vaših otaca, razjario se na Judejce i zato ih je predao u vaše ruke te ste ih gnjevno pobili da je do neba doprlo."},{"v":10,"t":"A sada još mislite podjarmiti Judejce i Jeruzalemce da vam budu robovi i robinje; a ipak, niste li i vi puni krivice prema Jahvi, svome Bogu?"},{"v":11,"t":"Zato me poslušajte sada i vratite to roblje što ga zarobiste od svoje braće, jer će se izliti na vas Jahvin gnjev.”"},{"v":12,"t":"Tada ustadoše neki između glavara Efrajimovih sinova, i to Johananov sin Azarja, Mešilemotov sin Berekja i Šalumov sin Ezekija, Hadlajev sin Amasa, na one što su se vraćali s vojske."},{"v":13,"t":"Pa im rekoše: “Nemojte dovoditi ovamo toga roblja, jer, uz krivicu koja je na nama pred Jahvom, vi mislite još dometnuti na naše grijehe i na našu krivicu, kao da nije dosta velika naša krivica i jarosni gnjev na Izraelu.”"},{"v":14,"t":"Tada ostaviše ratnici roblje i plijen pred knezovima i svim zborom."},{"v":15,"t":"Onda su poimence prozvani ljudi ustali, osokolili robove, obukli sve gole u odjeću iz plijena; a kad su ih obukli, obuli, nahranili, napojili i namazali, poveli su na magarcima sve iznemogle i odveli ih u palmov grad Jerihon do njihove braće, a potom se vratili u Samariju."},{"v":16,"t":"U to je doba kralj Ahaz zamolio asirske kraljeve da mu pomognu."},{"v":17,"t":"Edomci bijahu opet navalili i porazili Judejce te ih odveli u roblje."},{"v":18,"t":"Filistejci se raširili po gradovima Judejske Šefele i Negeba i, zauzevši Bet-Šemeš, Ajalon, Gederot i Soko sa selima, Timnu sa selima i Gimzo sa selima, nastanili se ondje."},{"v":19,"t":"Jahve je počeo ponižavati Judejce zbog judejskoga kralja Ahaza, jer je Ahaz razuzdao Judejce i teško se iznevjerio Jahvi."},{"v":20,"t":"Došao je na nj asirski kralj Tiglat-Pileser i pritijesnio ga umjesto da ga utvrdi."},{"v":21,"t":"Ahaz bijaše opljačkao Jahvin Dom, kraljevski dvor i knezove, i sve to dao asirskom kralju, ali mu ništa nije pomoglo."},{"v":22,"t":"Dok je bio u nevolji, postao je još nevjerniji Jahvi; takav je bio kralj Ahaz."},{"v":23,"t":"Počeo je žrtvovati damaščanskim bogovima koji su ga porazili, misleći: “Kad bogovi aramejskih kraljeva njima pomažu, žrtvovat ću im da bi i meni pomagali.” Ali su oni bili na propast njemu i svem Izraelu."},{"v":24,"t":"Ahaz je pokupio posuđe iz Božjega Doma, slupao ga, zatvorio vrata Jahvina Doma i podigao žrtvenike po svim uglovima u Jeruzalemu."},{"v":25,"t":"I u svakom je pojedinom judejskom gradu podigao uzvišice da kadi tuđim bogovima, dražeći Jahvu, Boga otaca."},{"v":26,"t":"Ostala su njegova djela i svi njegovi putovi, od prvih do posljednjih, zapisani u Knjizi o judejskim i izraelskim kraljevima."},{"v":27,"t":"Onda je Ahaz počinuo kod otaca. Sahranili su ga u Gradu, u Jeruzalemu, ali ga nisu unijeli u grobnicu judejskih kraljeva. Na njegovo se mjesto zakraljio sin mu Ezekija."}]},"29":{"hr":[{"v":1,"t":"Ezekiji je bilo dvadeset i pet godina kad se zakraljio. Kraljevao je dvadeset i devet godina u Jeruzalemu. Materi mu je bilo ime Abija, kći Zaharijina."},{"v":2,"t":"Činio je što je pravo u očima Jahvinim, sasvim kao i njegov otac David."},{"v":3,"t":"Prve godine prvoga mjeseca svojega kraljevanja otvorio je vrata Doma Jahvina i popravio ih."},{"v":4,"t":"Onda je pozvao svećenike i levite i, sabravši ih na istočni trg,"},{"v":5,"t":"rekao: “Čujte me, leviti! Sada se posvetite i posvetite Dom Jahve, Boga svojih otaca, i uklonite nečist iz Svetinje."},{"v":6,"t":"Naši su se oci iznevjerili i radili što je zlo u očima Jahve, našega Boga. Ostavili su ga i odvratili lice od Jahvina Prebivališta, okrenuvši mu leđa."},{"v":7,"t":"Zatvorili su trijemska vrata i potrnuli svjetiljke; nisu kadili kadom niti su prinosili paljenice u Svetištu Izraelova Boga."},{"v":8,"t":"Zato se Jahve rasrdio na Judejce i na Jeruzalem te je dopustio da budu zlostavljeni i da budu na užas i ruglo, kako vidite svojim očima."},{"v":9,"t":"I očevi su nam, eto, pali od mača, a sinovi, kćeri i žene zato su nam u ropstvu."},{"v":10,"t":"Sad sam, dakle, namislio u svom srcu sklopiti Savez s Jahvom, Izraelovim Bogom, da bi se odvratio od nas njegov jarosni gnjev."},{"v":11,"t":"Moja djeco, sad se nemojte lijeniti, jer vas je izabrao Jahve da stojite pred njim, da mu služite i da mu budete službenici i da mu kadite.”"},{"v":12,"t":"Tada ustadoše leviti: Amasajev sin Mahat i Azarjin sin Joel od Kehatovih sinova; od Merarijevih sinova: Abdijev sin Kiš i Jehalelelov sin Azarja; od Geršonovaca: Zimin sin Joah i Joahov sin Eden;"},{"v":13,"t":"od Elisafanovih sinova: Šimri i Jeiel; od Asafovih sinova: Zaharija i Matanija;"},{"v":14,"t":"od Hemanovih sinova: Jehiel i Šimej; od Jedutunovih sinova: Šemaja i Uziel."},{"v":15,"t":"Oni skupiše braću, posvetiše se i dođoše kako je bio zapovjedio kralj po Jahvinim riječima da očiste Jahvin Dom."},{"v":16,"t":"Svećenici uđoše u Jahvin Dom da ga očiste. Počeli su svu nečist što su je našli u Jahvinu Hekalu iznositi u predvorje Jahvina Doma; leviti su je primali iznoseći je napolje na potok Kidron."},{"v":17,"t":"Počeli su posvećivati prvoga dana prvoga mjeseca, a osmoga su dana istoga mjeseca ušli u Jahvin trijem; posvećivali su Jahvin Dom osam dana; šesnaestoga su dana prvoga mjeseca završili."},{"v":18,"t":"Onda su ušli kralju Ezekiji i rekli: “Očistili smo sav Jahvin Dom: žrtvenik za paljenice sa svim njegovim priborom, stol za prinesene kruhove sa svim njegovim priborom,"},{"v":19,"t":"a sve posuđe koje bijaše zabacio kralj Ahaz za svojega kraljevanja i nevjere opet smo obnovili i posvetili; eno ga pred Jahvinim žrtvenikom.”"},{"v":20,"t":"Tada kralj Ezekija porani, skupi gradske knezove i ode u Jahvin Dom."},{"v":21,"t":"Dovedoše sedam mladih junaca, sedam ovnova, sedam jaganjaca, sedam jaraca za okajnicu, za kraljevstvo i za Svetište i za Judu; on zapovjedi Aronovim sinovima svećenicima da ih prinesu za paljenicu na Jahvinu žrtveniku."},{"v":22,"t":"Zaklavši goveda, svećenici uzeše krv i poškropiše žrtvenik; zaklaše ovnove i krvlju poškropiše žrtvenik, zaklaše jaganjce i krvlju poškropiše žrtvenik."},{"v":23,"t":"Dovedoše jarce za okajnicu pred kralja i pred zbor te metnuše ruke na njih."},{"v":24,"t":"Onda ih zaklaše svećenici i prinesoše kao okajnicu njihovu krv na žrtveniku da izvrše obred pomirenja za sav Izrael, jer kralj bijaše zapovjedio da se prinese paljenica i okajnica za sav Izrael."},{"v":25,"t":"Postavio je u Jahvinu Domu levite s cimbalima, harfama i citrama, kako bijaše zapovjedio David, kraljev vidjelac Gad i prorok Natan, jer je od Jahve dolazila zapovijed po njegovim prorocima."},{"v":26,"t":"Tako su leviti stajali s Davidovim glazbalima, a svećenici s trubama."},{"v":27,"t":"Tada Ezekija zapovjedi da prinesu paljenice na žrtveniku. Kad se stala prinositi paljenica, počela je Jahvina pjesma uz trube i uz glazbala izraelskoga kralja Davida."},{"v":28,"t":"Sav se zbor klanjao, pjevači pjevali, a trubači trubili, i to sve dok se nije svršila paljenica."},{"v":29,"t":"Kad se svršilo prinošenje paljenice, kralj i svi koji bijahu s njim pobožno padoše na koljena i pokloniše se."},{"v":30,"t":"Onda su kralj i knezovi zapovjedili levitima da hvale Jahvu riječima Davida i vidioca Asafa; oni su počeli hvaliti s najvećim veseljem i, pavši ničice, poklonili se."},{"v":31,"t":"Tada Ezekija progovori: “Sada ste posvetili ruke Jahvi; pristupite i donesite klanice i zahvalnice u Dom Jahvin.” Sav je zbor donio klanice i zahvalnice. Tko je god bio spremna srca, prinio je paljenice."},{"v":32,"t":"Paljenica što ih je donio zbor bijaše na broj: sedamdeset goveda, sto ovnova, dvjesta jaganjaca, sve za paljenice Jahvi."},{"v":33,"t":"Ostalih posvećenih darova bilo je šest stotina goveda i tri tisuće grla sitne stoke."},{"v":34,"t":"Ali je svećenika bilo premalo, tako da nisu mogli oderati svih paljenica; zato su im pomagala braća leviti, dok se nije svršio posao i dok se nisu posvetili drugi svećenici, jer su leviti bili gorljiviji srcem da se posvete nego svećenici."},{"v":35,"t":"Bilo je i mnogo paljenica s pretilinom od pričesnica i s ljevanicama na paljenice. Tako se opet obnovila služba u Jahvinu Domu."},{"v":36,"t":"I Ezekija se veselio, i sav narod s njime, što je Bog spremio narodu, jer se sve to iznenada dogodilo."}]},"30":{"hr":[{"v":1,"t":"Potom Ezekija poruči svim Izraelcima i Judejcima pa napisa i pisma Efrajimovu i Manašeovu plemenu da dođu u Jahvin Dom u Jeruzalem da proslave Pashu Jahvi, Izraelovu Bogu."},{"v":2,"t":"Kralj, vijećajući s knezovima i sa svim zborom u Jeruzalemu, odluči da slave Pashu drugoga mjeseca."},{"v":3,"t":"Toga nisu mogli učiniti u pravo vrijeme jer nije bilo dosta posvećenih svećenika, i narod se ne bijaše skupio u Jeruzalemu."},{"v":4,"t":"I to je bilo prÓavo u kraljevim očima i u očima svega zbora,"},{"v":5,"t":"pa su odredili da se oglasi po svem Izraelu od Beer Šebe pa do Dana da dođu i proslave Pashu Jahvi, Izraelovu Bogu, u Jeruzalemu, jer je premnogi nisu svetkovali kako je propisano."},{"v":6,"t":"Tako su otišli glasnici s pismima od kralja i njegovih knezova po svem Izraelu i Judi te su govorili po kraljevoj zapovijedi: “Izraelovi sinovi, obratite se Jahvi, Abrahamovu, Izakovu i Izraelovu Bogu, pa će se i on obratiti k Ostatku koji vam je ostao od ruku asirskih kraljeva."},{"v":7,"t":"I nemojte biti kao vaši očevi i vaša braća, koji su se iznevjerili Jahvi, Bogu svojih otaca, te ih je predao propasti, kako i sami vidite."},{"v":8,"t":"Nemojte, dakle, biti tvrdovrati kao vaši očevi: pružite ruku Jahvi i dođite u njegovu Svetinju koju je posvetio zauvijek i služite Jahvi, svome Bogu, pa će odvratiti od vas svoj žestoki gnjev."},{"v":9,"t":"Ako se obratite Jahvi, vaša će braća i vaši sinovi naći milost u onih koji su ih zarobili pa će se vratiti u ovu zemlju; jer je Jahve, vaš Bog, milostiv i milosrdan i neće odvratiti lica od vas ako se vi obratite njemu.”"},{"v":10,"t":"I tako su glasnici krenuli od grada do grada po Efrajimovoj i Manašeovoj zemlji pa do Zebuluna, a ljudi im se podsmijavali i rugali."},{"v":11,"t":"Ipak su se neki od Ašerova, od Manašeova i od Zebulunova plemena ponizili i došli u Jeruzalem."},{"v":12,"t":"Na Judejce je pak sišla Božja ruka i prožela ih jednodušnošću da čine što bijaše zapovjedio kralj i knezovi po Jahvinoj riječi."},{"v":13,"t":"Skupilo se u Jeruzalemu mnogo naroda da slave Blagdan beskvasnih kruhova, drugoga mjeseca; zbor je bio vrlo velik."},{"v":14,"t":"Tada su ustali i uklonili žrtvenike što su bili u Jeruzalemu, uklonili sve kadionike i bacili ih u potok Kidron."},{"v":15,"t":"Onda su stali klati Pashu četrnaestoga dana drugoga mjeseca, a svećenici i leviti postidjeli se i, posvetiv se, počeli unositi paljenice u Jahvin Dom."},{"v":16,"t":"Stali su na svoje mjesto po pravilu, po Zakonu Mojsija, čovjeka Božjeg; svećenici su škropili krvlju primajući je iz ruku levita."},{"v":17,"t":"Kako ih bijaše mnogo u zboru koji se nisu posvetili, leviti su klali pashalne jaganjce za sve koji nisu bili čisti, da bi ih posvetili Jahvi."},{"v":18,"t":"Najveći se dio naroda, mnogi od Efrajimova i Manašeova, Jisakarova i Zebulunova plemena, nije očistio te je jeo Pashu nepropisno. Ali se za njih pomolio Ezekija govoreći: “Blagi Jahve neka očisti od grijeha svakoga"},{"v":19,"t":"tko je upravio srce da traži Boga Jahvu, Boga svojih otaca, ako i nije čist kako dolikuje Svetištu!”"},{"v":20,"t":"Jahve je uslišio Ezekiju i oprostio narodu."},{"v":21,"t":"Tako su Izraelovi sinovi koji su se zatekli u Jeruzalemu svetkovali Blagdan beskvasnih kruhova sedam dana s velikim veseljem, a leviti i svećenici hvalili Jahvu iz dana u dan uz glazbala za Jahvinu slavu."},{"v":22,"t":"Ezekija je hrabrio levite koji su pokazivali divnu privrženost Jahvi. Jeli su svečanu žrtvu sedam dana, žrtvujući žrtve pričesnice i slaveći Jahvu, Boga svojih otaca."},{"v":23,"t":"Potom je sav zbor vijećajući odlučio da svetkuje još sedam dana; svetkovali su još sedam dana s veseljem."},{"v":24,"t":"Judejski kralj Ezekija darovao je zboru tisuću mladih junaca i sedam tisuća grla sitne stoke; a knezovi darivali zboru tisuću mladih junaca i deset tisuća grla sitne stoke; tada se posvetilo mnogo svećenika."},{"v":25,"t":"Tako se proveselio sav judejski zbor, i svećenici i leviti, i sav zbor što je bio došao iz Izraela, i došljaci koji bijahu došli iz zemlje izraelske, i stanovnici u Judeji."},{"v":26,"t":"Bilo je veliko veselje u Jeruzalemu, jer od vremena Davidova sina Salomona, izraelskoga kralja, nije bilo tako u Jeruzalemu."},{"v":27,"t":"Onda su ustali svećenici i leviti te blagoslovili narod: njihov je glas bio uslišan, a njihova je molitva doprla do Božjega svetog Prebivališta na nebu."}]},"31":{"hr":[{"v":1,"t":"Kad se sve to svršilo, svi Izraelovi sinovi koji su se našli ondje zađoše po judejskim gradovima te su razbijali stupove, sjekli ašere i obarali uzvišice i žrtvenike po svem Judinu, Benjaminovu, Efrajimovu i Manašeovu plemenu dokle god nisu završili. Onda se svi Izraelovi sinovi vratiše svaki na svoj posjed, u svoje gradove."},{"v":2,"t":"Ezekija je opet uredio svećeničke i levitske redove po njihovim redovima, svakoga prema njegovoj službi, svećenike i levite, za paljenice i za pričesnice, da služe, slave i hvale Boga na vratima Jahvina tabora."},{"v":3,"t":"Odredio je kraljevski doprinos od svoga imanja za paljenice, za paljenice jutarnje i večernje i za paljenice što se prinose subotom, za mlađaka i na blagdane, kako je napisano u Zakonu Jahvinu."},{"v":4,"t":"Zapovjedio je narodu, jeruzalemskim stanovnicima, da daju dio svećenicima i levitima da se utvrde u Zakonu Jahvinu."},{"v":5,"t":"Kad se to razglasilo, počeli su Izraelovi sinovi donositi najboljega žita, novog vina, ulja i meda i svakojaka poljskog priroda i donosili su obilne desetine od svega."},{"v":6,"t":"Izraelovi i Judini sinovi, koji su živjeli u judejskim gradovima, također su donosili desetinu od goveda i sitne stoke i desetinu od svetih stvari posvećenih Jahvi, njihovu Bogu; donosili su i davali sve hrpu na hrpu."},{"v":7,"t":"Trećega su mjeseca počeli slagati u hrpe, a sedmoga su mjeseca završili."},{"v":8,"t":"Onda je došao Ezekija s knezovima i, ugledavši hrpe, blagosloviše Jahvu i njegov izraelski narod."},{"v":9,"t":"Potom se Ezekija propitao kod svećenika i levita za hrpe."},{"v":10,"t":"Odgovarajući, svećenički poglavar Azarja, od Sadokova doma, reče: “Otkako su počeli donositi ove prinose u Dom Jahvin, jedemo i siti smo, a mnogo i pretječe, jer je Jahve blagoslovio svoj narod te je preteklo ovo mnoštvo.”"},{"v":11,"t":"Tada Ezekija zapovjedi da se urede sobe u Jahvinu Domu; kad su ih spremili,"},{"v":12,"t":"počeli su onamo unositi prinose, desetine i svetinje; nad tim je bio predstojnik levit Konanija i brat mu Šimej, drugi do njega."},{"v":13,"t":"A Jehiel, Azazja, Nahat, Asahel, Jerimot, Jozabad, Eliel, Jismakja, Mahat i Benaja biše postavljeni kao nadglednici uz Konaniju i brata mu Šimeja, po nalogu kralja Ezekije i Azarje, predstojnika u Božjem Domu."},{"v":14,"t":"Kore, sin levita Jimne, vratar Istočnih vrata, bio je nad dragovoljnim Božjim prinosima da bi prinosio Jahvine podizanice i svetinje nad svetinjama."},{"v":15,"t":"Pod njim su bili Eden, Minjamin, Ješua, Šemaja, Amarja i Šekanija po svećeničkim gradovima da savjesno dijele svojoj braći po njihovim redovima, kako velikome tako i malome -"},{"v":16,"t":"osim muškaraca starijih od trideset godina popisanih u rodovnicima - svima koji su dolazili u Dom Jahvin na svoj svakidašnji posao da obave obredne dužnosti po svojim redovima."},{"v":17,"t":"U rodovnike su bili popisani svećenici po obiteljima i leviti od dvadeset godina naviše po svojim službama, po svojim redovima."},{"v":18,"t":"U rodovnike bijahu popisana sva njihova djeca, njihove žene, njihovi sinovi i njihove kćeri, za svekoliki zbor, jer su se iskreno posvetili svetinjama."},{"v":19,"t":"Aronovi sinovi, svećenici na poljskim pašnjacima svojih gradova, u svakom pojedinom gradu, bijahu poimence određeni da daju dio svakome muškarcu među svećenicima. Sve su rodovnike sastavili leviti."},{"v":20,"t":"Ezekija je uradio tako po svoj Judeji čineći što je dobro, pravo i vjerno pred Jahvom, svojim Bogom."},{"v":21,"t":"U svakom poslu koji je počeo za službu Božjega Doma, i u zakonu i u zapovijedi tražeći Boga, trudio se svim svojim srcem i uspijevao."}]},"32":{"hr":[{"v":1,"t":"Poslije tih događaja i dokaza vjernosti dođe asirski kralj Sanherib i, ušavši u Judeju, opkoli tvrde gradove misleći ih osvojiti."},{"v":2,"t":"Ezekija, vidjevši gdje je došao Sanherib i kako snuje da zavojšti na Jeruzalem,"},{"v":3,"t":"posavjetova se s knezovima i s junacima da začepi vodene izvore koji bijahu izvan grada. Oni mu podupriješe osnovu."},{"v":4,"t":"Sabralo se mnogo naroda te su začepili sva vrela i potok koji teče posred zemlje; govorahu: “Zašto da asirski kraljevi nađu toliko vode kad dođu!”"},{"v":5,"t":"Ezekija se osokolio, obnovio sav oboreni zid i podigao kule na njemu; izvana je sagradio drugi zid i utvrdio Milon u Davidovu gradu; napravio je mnogo kopalja i štitova,"},{"v":6,"t":"zatim postavio vojvode nad narodom i, pozvavši ih k sebi na trg kraj gradskih vrata, ohrabri ih ovim riječima:"},{"v":7,"t":"“Budite hrabri i junaci; ne bojte se i ne plašite se asirskoga kralja, ni svega mnoštva što je s njim, jer je s nama moćniji nego s njim:"},{"v":8,"t":"s njim je tjelesna mišica, a s nama je Jahve, Bog naš, da nam pomaže i da bije naše bojeve.” Narod se uzda u riječi judejskoga kralja Ezekije."},{"v":9,"t":"Poslije toga asirski je kralj Sanherib, dok bijaše kod Lakiša sa svom bojnom silom, poslao sluge u Jeruzalem k judejskome kralju Ezekiji i k svim Judejcima koji bijahu u Jeruzalemu i poručio im:"},{"v":10,"t":"“Ovako veli asirski kralj Sanherib: 'U što se uzdate stojeći opsjednuti u Jeruzalemu?"},{"v":11,"t":"Ne zavodi li vas Ezekija da vas preda smrti od gladi i žeđi kad govori: Jahve, Bog naš, izbavit će nas iz ruke asirskoga kralja?"},{"v":12,"t":"Nije li taj Ezekija uklonio njegove uzvišice i njegove žrtvenike; i zapovjedio Judejcima i Jeruzalemcima govoreći: Pred jednim se žrtvenikom klanjajte i na njemu kadite!"},{"v":13,"t":"Zar ne znate što sam učinio ja i moji preci od svih zemaljskih naroda? Zar su bogovi zemaljskih naroda mogli izbaviti svoje zemlje iz moje ruke?"},{"v":14,"t":"Koji je među svim bogovima onih naroda što su ih sasvim uništili moji preci mogao izbaviti narod iz moje ruke, da bi mogao vaš Bog izbaviti vas iz moje ruke?'"},{"v":15,"t":"Zato nemojte da vas sada Ezekija vara i da vas tako zavodi i ne vjerujte mu! Jer nijedan bog nikojega naroda ili kraljevstva nije mogao izbaviti svoga naroda iz moje ruke, ni iz ruke mojih predaka, a kamoli će vaš Bog izbaviti vas iz moje ruke!”"},{"v":16,"t":"Još su više njegove sluge napadale Boga Jahvu i njegova slugu Ezekiju."},{"v":17,"t":"Napisao je i pismo ružeći Jahvu, Izraelova Boga: “Kao što bogovi zemaljskih naroda nisu izbavili svojih naroda iz moje ruke, tako neće ni Ezekijin Bog izbaviti svojega naroda iz moje ruke.”"},{"v":18,"t":"I vikahu iza glasa, na judejskom jeziku, jeruzalemskom narodu koji bijaše na zidu da ga uplaše i prepadnu kako bi osvojili grad."},{"v":19,"t":"Govorili su o jeruzalemskom Bogu kao o bogovima zemaljskih naroda, bogovima koji su djelo čovječjih ruku."},{"v":20,"t":"Stoga se pomoli kralj Ezekija i prorok Izaija, Amosov sin, i zazvaše nebo u pomoć."},{"v":21,"t":"Tada Jahve posla anđela koji uništi sve hrabre junake, zapovjednike i vojvode u vojsci asirskoga kralja, tako da se vratio posramljen u svoju zemlju. A kad je ušao u hram svoga boga, sasjekli su ga ondje mačem neki koji su se rodili iz njegova krila."},{"v":22,"t":"Tako je Jahve spasio Ezekiju i jeruzalemske stanovnike od ruke asirskoga kralja Sanheriba i iz ruku neprijatelja, te im dao mir odasvud uokolo."},{"v":23,"t":"Mnogi su donosili darove Jahvi u Jeruzalem i dragocjenosti judejskome kralju Ezekiji. Poslije toga Ezekija se uzvisio u očima svih naroda."},{"v":24,"t":"U to se vrijeme Ezekija razbolio nasmrt, ali se pomolio Jahvi, koji mu je progovorio i učinio čudo."},{"v":25,"t":"Ali se Ezekija nije odužio dobročinstvu koje mu je iskazano, nego se uzoholio; stoga je došla srdžba na nj, na Judu i na Jeruzalem."},{"v":26,"t":"Ezekija se ponizio zato što mu se bilo uzoholilo srce, i on i Jeruzalemci, pa tako nije došla na njih Jahvina srdžba za Ezekijina života."},{"v":27,"t":"Ezekija je stekao vrlo veliko bogatstvo i slavu; napravio je riznice za srebro i zlato, za drago kamenje, za miomirise, za štitove i za svakojake dragocjene posude;"},{"v":28,"t":"skladište za prirod od žita, od novog vina i ulja, staje za svakojaku stoku, torove za stada."},{"v":29,"t":"Podigao je i gradove, imao je mnogo blaga, sitne stoke i goveda, jer mu je Bog dao vrlo veliko imanje."},{"v":30,"t":"Isti je Ezekija začepio gornji izvor Gihonske vode i svrnuo je pravo na zapadnu stranu Davidova grada. Ezekija je bio sretan u svakom poslu."},{"v":31,"t":"Samo kad su došli poslanici babilonskih knezova, poslani k njemu da se propitaju za čudo koje se dogodilo u zemlji, ostavio ga je Bog da bi ga iskušao i da bi se doznalo sve što mu je u srcu."},{"v":32,"t":"Ostala Ezekijina djela, njegova pobožnost, zapisani su u proročkom viđenju proroka Izaije, Amosova sina, i u Knjizi o judejskim i izraelskim kraljevima."},{"v":33,"t":"Ezekija je počinuo kod svojih otaca. Sahranili su ga na usponu kako se ide ka grobovima Davidovih sinova. Po smrti su mu odali počast svi Judejci i Jeruzalemci. Na njegovo se mjesto zakraljio sin mu Manaše."}]},"33":{"hr":[{"v":1,"t":"Manašeu je bilo dvanaest godina kad se zakraljio. Pedeset i pet godina kraljevao je u Jeruzalemu."},{"v":2,"t":"Činio je što je zlo u Jahvinim očima, povodeći se za gnusobama naroda što ih je Jahve protjerao pred sinovima Izraelovim."},{"v":3,"t":"Obnovio je uzvišice što ih bijaše oborio otac mu Ezekija, podigao je žrtvenike Baalu, načinio ašere i stao se klanjati svoj nebeskoj vojsci i služiti joj."},{"v":4,"t":"Podigao je žrtvenike i u Domu Jahvinu, za koji bijaše rekao Jahve: “U Jeruzalemu će prebivati Ime moje zauvijek.”"},{"v":5,"t":"Sagradio je žrtvenike svoj nebeskoj vojsci u oba predvorja Doma Jahvina."},{"v":6,"t":"I sinove je svoje proveo kroz oganj u dolini Hinomova sina. Vračao je, gatao, čarao, stvorio bajače i opsjenare i uopće učinio premnogo zla u Jahvinim očima razjarujući ga."},{"v":7,"t":"Načinio je idolski lik i posadio ga u Domu Božjem, za koji Bog bijaše rekao Davidu i njegovu sinu Salomonu: “U ovom Domu i u Jeruzalemu, koji sam izabrao među svim izraelskim plemenima, postavit ću Ime svoje zauvijek."},{"v":8,"t":"Neću više dati da noga Izraelaca uzmakne iz zemlje koju sam dao u baštinu vašim očevima, samo ako budu držali i provodili u djelo sve što sam im zapovjedio: sav Zakon, uredbe i običaje dane preko Mojsija.”"},{"v":9,"t":"Ali je Manaše zaveo Judejce i Jeruzalemce te su radili još gore nego narodi što ih je Jahve iskorijenio pred sinovima Izraelovim."},{"v":10,"t":"Jahve je opominjao Manašea i njegov narod, ali oni nisu poslušali."},{"v":11,"t":"Stoga je Jahve doveo na njih vojskovođe asirskoga kralja. Uhvativši Manašea kukama, svezali su ga u dvoje mjedene verige i odveli u Babilon."},{"v":12,"t":"Kad se našao u nevolji, počeo se moliti za milost Jahvi, svome Bogu, ponizivši se veoma pred Bogom otaca."},{"v":13,"t":"Molio se i Bog mu se smilovao te usliša njegovu prošnju i vrati ga u Jeruzalem u kraljevstvo. Manaše tada spozna da je Jahve Bog."},{"v":14,"t":"Poslije toga sagradio je vanjski zid Davidovu gradu zapadno od Gihona, od doline pa do Ribljih vrata, i opasao zidom Ofel, izvevši ga vrlo visoko. Postavio je bojne vojvode u svim tvrdim gradovima u Judi."},{"v":15,"t":"Osim toga, uklonio je iz Jahvina Doma tuđinske bogove, onaj idolski lik i sve žrtvenike što ih bijaše posagradio na gori Jahvina Doma i u Jeruzalemu i sve ih baci izvan grada."},{"v":16,"t":"Zatim opet podiže Jahvin žrtvenik i žrtvova na njemu žrtve pričesnice i zahvalnice. Zapovjedi i Judejcima da služe Jahvi, Bogu Izraelovu."},{"v":17,"t":"Ipak je narod još žrtvovao po uzvišicama, ali samo Jahvi, svojem Bogu."},{"v":18,"t":"Ostala Manašeova djela i njegova molitva Bogu, riječi koje su mu govorili vidioci u ime Jahve, Izraelova Boga, zapisane su u Povijesti izraelskih kraljeva."},{"v":19,"t":"Njegova molitva i kako je bio uslišan, svi njegovi grijesi i njegova nevjera te mjesta na kojima je pogradio uzvišice, podigao ašere i idole prije nego što se ponizio - sve je to zapisano u povijesti Hozajevoj."},{"v":20,"t":"Tada Manaše počinu kraj svojih otaca. Sahranili su ga u dvoru. Na njegovo se mjesto zakraljio sim mu Amon."},{"v":21,"t":"Dvadeset su i dvije godine bile Amonu kad se zakraljio, a kraljevao je dvije godine u Jeruzalemu."},{"v":22,"t":"Činio je što je zlo u Jahvinim očima, kao i otac mu Manaše, jer je svim idolima koje bijaše načinio njegov otac Manaše on prinosio žrtve i služio im."},{"v":23,"t":"Ali se nije ponizio pred Jahvom kako se ponizio otac mu Manaše, nego je još i umnožio svoju krivicu."},{"v":24,"t":"Tada se protiv njega urotiše njegove sluge i ubiše ga u dvoru."},{"v":25,"t":"Ali je prosti puk pobio sve one koji se bijahu urotili protiv kralja Amona i na njegovo mjesto zakraljio sina mu Jošiju."}]},"34":{"hr":[{"v":1,"t":"Jošiji je bilo osam godina kad se zakraljio. Kraljevao je trideset i jednu godinu u Jeruzalemu."},{"v":2,"t":"Činio je što je pravo u Jahvinim očima. U svemu je hodio putovima oca Davida, ne skrećući ni desno ni lijevo."},{"v":3,"t":"Osme godine kraljevanja, dok još bijaše dječak, počeo je tražiti Boga oca Davida, a dvanaeste je godine stao čistiti Judeju i Jeruzalem od uzvišica, ašera, od rezanih i livenih likova."},{"v":4,"t":"Pred njim su oborili žrtvenike Baalu, polomio je sunčane stupove koji bijahu na njima; izlomio je i satro ašere i rezane i livene likove, prosuo ih po grobovima onih što su im prinosili žrtve."},{"v":5,"t":"Svećeničke je kosti spalio na njihovim žrtvenicima i tako očistio Judeju i Jeruzalem."},{"v":6,"t":"Isto je učinio i po gradovima Manašeova, Efrajimova i Šimunova plemena, pa do Naftalijeva, po njihovim opustošenim mjestima unaokolo."},{"v":7,"t":"Oborio je žrtvenike i ašere, raskovao i satro rezane likove i isjekao sve sunčane stupove po svoj zemlji izraelskoj, a onda se vratio u Jeruzalem."},{"v":8,"t":"Osamnaeste godine kraljevanja, očistivši zemlju i Dom, posla Asalijahina sina Šafana, gradskoga upravitelja Maaseju, Johazova sina Joaha, tajnika, da poprave Dom Jahve, njegova Boga."},{"v":9,"t":"Oni su došli k velikom svećeniku Hilkiji i predali mu novce donesene u Božji Dom, koje bijahu sabrali leviti, čuvari hramskog praga, iz ruke Manašeovih i Efrajimovih sinova i od svega Izraelova Ostatka, od svega Judina i Benjaminova plemena, od jeruzalemskih stanovnika."},{"v":10,"t":"Dali su to na ruku poslovođama, postavljenim nad Domom Jahvinim, a oni su izdavali poslenicima koji su radili u Domu Jahvinu, popravljajući što je bilo trošno i obnavljajući Hram."},{"v":11,"t":"Dali su drvodjeljama i graditeljima da kupuju tesanac i drvo za grede i da se pobrvnaju kuće koje bijahu porušili judejski kraljevi."},{"v":12,"t":"Ti su ljudi savjesno obavljali posao; nad njima su bili postavljeni Jahat i Obadja, leviti od Merarijevih sinova, i Zaharija i Mešulam od Kehatovih sinova da upravljaju radom. Svi su leviti bili vični glazbalima."},{"v":13,"t":"Jedni su bili nad bremenošama i nadstojnicima svih poslenika u svakoj službi, a drugi su od levita bili pisari, nadzornici i vratari."},{"v":14,"t":"Kad su iznosili novce donesene u Jahvin Dom, našao je svećenik Hilkija Knjigu Zakona Jahvina, danu preko Mojsija."},{"v":15,"t":"I, progovorivši, Hilkija reče tajniku Šafanu: “Našao sam Knjigu Zakona u Domu Jahvinu.” Hilkija dade knjigu Šafanu."},{"v":16,"t":"Šafan odnese knjigu kralju i izvjesti ga: “Tvoje sluge rade sve što im se povjerilo."},{"v":17,"t":"Izasuvši novce što su se našli u Domu Jahvinu, dadoše ih na ruku poslovođama i poslenicima.”"},{"v":18,"t":"Tada tajnik Šafan javi kralju: “Svećenik Hilkija dade mi jednu knjigu.” I Šafan je poče čitati pred kraljem."},{"v":19,"t":"Čuvši riječi Zakona, kralj razdrije haljine svoje."},{"v":20,"t":"I naredi Hilkiji, Šafanovu sinu Ahikamu, Mikinu sinu Abdonu, tajniku Šafanu i kraljevu sluzi Asaji:"},{"v":21,"t":"“Idite i upitajte Jahvu o meni i Ostatku Izraela i Judeje zbog ove knjige što je nađena, jer je velika Jahvina jarost što se izlila na nas zato što naši očevi nisu čuvali Jahvine riječi, nisu vršili što je pisano u knjizi.”"},{"v":22,"t":"Hilkija s kraljevim ljudima ode proročici Huldi, ženi Šaluma, Tokhatova sina, sina Hasre, čuvara odjeće; ona je živjela u Jeruzalemu, u novom gradu. Kad joj to kazaše,"},{"v":23,"t":"ona im reče: “Ovako veli Jahve, Bog Izraelov: 'Kažite čovjeku koji vas je poslao k meni:"},{"v":24,"t":"Ovako veli Jahve: Evo, dovest ću nesreću na ovaj grad i na njegove stanovnike, izvršit ću sve kletve napisane u knjizi što je pročitaše pred judejskim kraljem."},{"v":25,"t":"Jer su me ostavili i kadili tuđim bogovima da bi me ljutili svim djelima ruku svojih, planut će jarost moja na to mjesto i neće se ugasiti."},{"v":26,"t":"A judejskome kralju, koji vas je poslao po Jahvin savjet, recite ovo: Ovako govori Jahve, Bog Izraelov: Riječi si čuo."},{"v":27,"t":"Ali kako ti je omekšalo srce i jer si se ponizio pred Bogom čuvši što sam objavio tome gradu i njegovim stanovnicima, i ponizivši se preda mnom, razdro si haljine i plakao, zato sam te uslišio - riječ je Jahvina!"},{"v":28,"t":"Evo, sjedinit ću te s ocima tvojim i s mirom ćeš leći u grob da ne vidiš svu nesreću koju ću svaliti na ovo mjesto i njegove stanovnike.'” Oni odnesoše taj odgovor kralju."},{"v":29,"t":"Tada posla kralj da se saberu sve judejske i jeruzalemske starješine."},{"v":30,"t":"Kralj se potom pope u Dom Jahvin, sa svim Judejcima, Jeruzalemcima, svećenicima, levitima i sa svim narodom, od najvećega do najmanjeg. I pročita im sve riječi Knjige Saveza što je nađena u Domu Jahvinu."},{"v":31,"t":"Kralj, stojeći na svome mjestu, obnovi pred Jahvom Savez da će slijediti Jahvu, držati se njegovih zapovijedi, pouka i uredaba svim srcem i svom dušom da bi izvršio sve stavke toga Saveza što su napisane u knjizi."},{"v":32,"t":"I sve koji su se našli u Jeruzalemu i Benjaminovu plemenu pozva da pristupe; i Jeruzalemci prionuše uza Savez Boga, Boga svojih otaca."},{"v":33,"t":"Tada Jošija ukloni sve gnusobe iz svih izraelskih krajeva i učini te svi koji su se našli u Izraelu počeše služiti Jahvi, svojem Bogu. Za svega njegova života nisu odstupili od Jahve, Boga svojih otaca."}]},"35":{"hr":[{"v":1,"t":"Potom je Jošija svetkovao Pashu Jahvi u Jeruzalemu: klalo se pashalno jagnje četrnaestoga dana prvoga mjeseca."},{"v":2,"t":"Postavio je svećenike na njihove službe, osokolivši ih na službu u Jahvinu Domu."},{"v":3,"t":"Zatim je rekao levitima koji su poučavali sve Izraelce i bili posvećeni Jahvi: “Metnite sveti Kovčeg u Dom koji je sagradio Davidov sin Salomon, izraelski kralj; ne smijete ga više nositi na ramenima; sada služite Jahvi, svojem Bogu, i njegovu izraelskom narodu!"},{"v":4,"t":"I pripravite se po otačkim domovima, po redovima, kako je napisao izraelski kralj David i propisao sin mu Salomon."},{"v":5,"t":"Stojte u Svetinji po redovima otačkih domova svoje braće, običnoga puka, i po redu levitskoga otačkog doma."},{"v":6,"t":"I tako koljite pashalno janje te se posvetite i pripravite svoju braću da svetkuju kako je zapovjedio Jahve preko Mojsija.”"},{"v":7,"t":"Jošija je darovao običnom puku od sitne stoke jaganjaca i jarića, sve za Pashu, svima koji su se našli ondje, na broj trideset tisuća, i tri tisuće goveda, sve to s kraljeva imanja."},{"v":8,"t":"Njegovi su knezovi dragovoljno darovali narodu, svećenicima i levitima, i to: Hilkija, Zaharija i Jehiel, predstojnici u Božjem Domu, dali su svećenicima za Pashu dvije tisuće i šest stotina jaganjaca i jarića i tri stotine goveda."},{"v":9,"t":"A Konanija, Šemaja i Netanel, njegova braća Hašabja, Jehiel i Jozabad, levitski knezovi, darovali su levitima za Pashu pet tisuća grla sitne stoke i pet stotina goveda."},{"v":10,"t":"A kad je bila uređena služba, stali su svećenici na svoje mjesto i leviti u svojim redovima po kraljevoj zapovijedi."},{"v":11,"t":"Klali su Pashu, a svećenici su škropili krvlju, dok su leviti odirali kožu."},{"v":12,"t":"Onda su pripravili paljenice da ih dadu običnom puku po redovima otačkih domova da ih prinese Jahvi, kako je napisano u Mojsijevoj knjizi. Tako su učinili i s govedima."},{"v":13,"t":"Pekli su Pashu na ognju po običaju, a ostale su posvećene stvari kuhali u loncima, kotlovima i zdjelama i brzo ih raznosili svemu običnom puku."},{"v":14,"t":"Poslije su pripravljali Pashu sebi i svećenicima, jer su svećenici, Aronovi sinovi, bili zaposleni prinošenjem paljenica i pretiline do noći; zato su leviti pripravljali sebi i svećenicima, Aronovim sinovima."},{"v":15,"t":"A pjevači, Asafovi sinovi, stajali su na svojem mjestu, kako je bio zapovjedio David, Asaf, Heman i kraljev vidjelac Jedutun. Vratari su stajali na svakim vratima; oni se nisu micali od službe, nego su im njihova braća leviti pripravljala sve."},{"v":16,"t":"Tako je bila uređena sva Jahvina služba onoga dana da se proslavi Pasha i da se prinesu paljenice na Jahvinu žrtveniku po zapovijedi kralja Jošije."},{"v":17,"t":"Tako su Izraelovi sinovi, koji su se našli ondje, u to doba sedam dana slavili Pashu i Blagdan beskvasnih kruhova."},{"v":18,"t":"Pasha kao ova u Izraelu nije se slavila od vremena proroka Samuela niti je ijedan od izraelskih kraljeva slavio Pashu kao što ju je slavio Jošija - sa svećenicima, levitima i sa svim Judejcima i Izraelcima, koliko ih se god našlo, i s Jeruzalemcima."},{"v":19,"t":"Ta se Pasha svetkovala osamnaeste godine Jošijina kraljevanja."},{"v":20,"t":"Poslije svega toga, kad je Jošija uredio Dom, došao je egipatski kralj Neko da se bije kod Karkemiša na Eufratu, a Jošija je izišao preda nj."},{"v":21,"t":"Kralj Neko poslao je Jošiji glasnike i poručio: “Što ja imam s tobom, judejski kralju? Ne idem ja danas na tebe, nego na dom s kojim sam u ratu, i Bog mi je zapovjedio da se požurim. Okani se Boga koji je sa mnom da te ne upropastim!”"},{"v":22,"t":"Ali Jošija nije odvratio lica od njega, nego se ojunačio da se bije s njim; ne poslušavši Nekovih riječi iz Božjih usta, došao je da se bije na Megidskom polju."},{"v":23,"t":"Strijelci ustrijeliše kralja Jošiju, a on reče slugama: “Izvedite me jer sam teško ranjen.”"},{"v":24,"t":"Sluge ga skinuše s bojnih kola i metnuše u druga kola koja je imao, pa ga odvezoše u Jeruzalem; ondje je umro i bio sahranjen u grobnici otaca. Sva Judeja s Jeruzalemom plakala je za Jošijom."},{"v":25,"t":"I Jeremija je protužio za Jošijom. I svi pjevači i pjevačice spominju u tužbalicama Jošiju do danas; uveli su ih u običaj u Izraelu, i eno su zapisane u Tužbalicama."},{"v":26,"t":"Ostala Jošijina djela i njegova pobožnost, vršeni onako kako piše u Jahvinu Zakonu,"},{"v":27,"t":"svi njegovi pothvati, od prvih do posljednjih, zapisani su u Knjizi o izraelskim i judejskim kraljevima."}]},"36":{"hr":[{"v":1,"t":"Tada priprosti puk uze Jošijina sina Joahaza i zakralji ga u Jeruzalemu namjesto njegova oca."},{"v":2,"t":"Dvadeset i tri godine bile su Joahazu kad se zakraljio. Kraljevao je tri mjeseca u Jeruzalemu."},{"v":3,"t":"Svrgao ga je egipatski kralj u Jeruzalemu i udario na zemlju danak od sto srebrnih talenata i jedan zlatni talenat."},{"v":4,"t":"Egipatski kralj postavi za kralja nad Judejom i nad Jeruzalemom njegova brata Elijakima, promijenivši mu ime na Jojakim; njegova je brata Joahaza uzeo Neko i odveo u Egipat."},{"v":5,"t":"Dvadeset je i pet godina bilo Jojakimu kad se zakraljio. Kraljevao je jedanaest godina u Jeruzalemu; činio je što je zlo u očima Jahve, njegova Boga."},{"v":6,"t":"Na nj je zaratio babilonski kralj Nabukodonozor i, svezavši ga u dvoje mjedene verige, odveo ga u Babilon."},{"v":7,"t":"Dio posuđa iz Jahvina Doma odnio je Nabukodonozor u Babilon i metnuo ga u svoj dvorac u Babilonu."},{"v":8,"t":"Ostala Jojakimova djela i gnusobe koje je činio i što se na njemu našlo, sve je zapisano u Knjizi o izraelskim i judejskim kraljevima. Na njegovo se mjesto zakraljio sin mu Jojakin."},{"v":9,"t":"Osam je godina bilo Jojakinu kad se zakraljio, a kraljevao je tri mjeseca i deset dana u Jeruzalemu; činio je što je zlo u Jahvinim očima."},{"v":10,"t":"O godišnjoj je mijeni poslao kralj Nabukodonozor te su ga odveli u Babilon s dragocjenostima iz Jahvina Doma, a nad Judom i nad Jeruzalemom zakraljio je njegova rođaka Sidkiju."},{"v":11,"t":"Dvadeset je i jedna godina bila Sidkiji kad se zakraljio, a kraljevao je jedanaest godina u Jeruzalemu."},{"v":12,"t":"Činio je što je zlo u očima Jahve, njegova Boga; nije se ponizio pred prorokom Jeremijom, koji mu je govorio iz Jahvinih usta,"},{"v":13,"t":"nego se još i pobunio protiv kralja Nabukodonozora, koji ga bijaše zakleo Bogom; ostao je tvrdoglav i uporan u srcu da se ne obrati Jahvi, Bogu Izraelovu."},{"v":14,"t":"Pa i svi su svećenički poglavari i narod gomilali nevjeru na nevjeru slijedeći gnusna djela krivobožačkih naroda, oskvrnjujući Dom Jahvin, posvećen u Jeruzalemu."},{"v":15,"t":"Jahve, Bog njihovih otaca, slao je k njima zarana svoje glasnike, slao ih svejednako, jer mu bijaše žao svojega naroda i svojega Prebivališta."},{"v":16,"t":"Ali su se oni rugali Božjim glasnicima, prezirući njegove riječi i podsmjehujući se njegovim prorocima, dok se nije podigla Jahvina jarost na njegov narod te više nije bilo lijeka."},{"v":17,"t":"Doveo je na njih kaldejskoga kralja, koji okrenu pod mač njihove mladiće u domu njihova Svetišta, ne štedeći ni mladića ni djevojke, ni starca ni nemoćna.Sve mu je predao u ruke."},{"v":18,"t":"Sve posuđe Božjega Doma, veliko i malo, blago Jahvina Doma i kraljevo blago, blago njegovih knezova, sve je odnio u Babilon."},{"v":19,"t":"Spalili su Božji Dom, oborili jeruzalemski zid i sve su njegove dragocjenosti uništili."},{"v":20,"t":"One što izbjegoše maču odvede Nabukodonozor u Babilon u sužanjstvo. Postali su robovi njemu i njegovim sinovima, dokle nije nastalo perzijsko kraljevstvo."},{"v":21,"t":"Da bi se ispunila riječ koju Jahve reče na Jeremijina usta: “Dokle se zemlja ne oduži svojim subotama, počivat će za sve vrijeme u pustoši dok se ne ispuni sedamdeset godina.”"},{"v":22,"t":"Ali prve godine perzijskoga kralja Kira, da bi se ispunila riječ Jahvina objavljena na Jeremijina usta, podiže Jahve duh perzijskoga kralja Kira te on oglasi po svemu svojem kraljevstvu usmeno i pismeno:"},{"v":23,"t":"“Ovako veli perzijski kralj Kir: 'Sva zemaljska kraljevstva dade mi Jahve, Bog nebeski. On mi naloži da mu sagradim Dom u Jeruzalemu, u Judeji. Tko je god među vama od svega njegova naroda, Bog njegov bio s njim, pa neka ide onamo!'”"}]}},"EZR":{"1":{"hr":[{"v":1,"t":"Prve godine perzijskoga kralja Kira, da bi se ispunila riječ Jahvina objavljena na Jeremijina usta, nadahnu Jahve perzijskoga kralja Kira te on objavi po svemu svojem kraljevstvu, usmeno i pismeno:"},{"v":2,"t":"“Ovako veli perzijski kralj Kir: 'Sva zemaljska kraljevstva dade mi Jahve, Bog nebeski. On mi naloži da mu sagradim Dom u Jeruzalemu, u Judeji."},{"v":3,"t":"Tko je god među vama od svega njegova naroda, Bog njegov bio s njim! Neka ide u Jeruzalem u Judeji i neka gradi Dom Jahvi, Bogu Izraelovu, Bogu koji stoluje u Jeruzalemu."},{"v":4,"t":"I gdje god se još zadržao ostatak toga naroda, neka ga stanovništvo mjesta u kojima boravi podupre srebrom i zlatom, imanjem i stokom i dragovoljnim prinosima za Dom Božji u Jeruzalemu.'”"},{"v":5,"t":"Tada ustadoše glavari obitelji Jude i Benjamina, svećenici i leviti, i svi kojima je Bog potaknuo duh i krenuše graditi Dom Jahvin u Jeruzalemu."},{"v":6,"t":"I svi su im susjedi pomagali: srebrom, zlatom, darovima u naravi, stokom, dragocjenostima mnogim, osim svega što su dragovoljno prilagali."},{"v":7,"t":"Kralj Kir iznese posuđe Jahvina Doma koje Nabukodonozor bijaše odnio iz Jeruzalema i stavio u hram svoga boga."},{"v":8,"t":"Kir, kralj perzijski, uruči ga Mitredatu, rizničaru, koji ga izbroji judejskom knezu Šešbasaru."},{"v":9,"t":"Evo njegova popisa. Zlatnih zdjela: trideset; srebrnih zdjela: tisuću i dvadeset devet;"},{"v":10,"t":"zlatnih čaša: trideset; srebrnih čaša: četiri stotine i deset; ostalog posuđa: tisuću."},{"v":11,"t":"Svega zlatnog i srebrnog posuđa: pet tisuća i četiri stotine. Sve je to odnio Šešbasar kada se sužnji vraćahu iz Babilona u Jeruzalem."}]},"2":{"hr":[{"v":1,"t":"Ovo su ljudi one pokrajine koji su se vratili iz sužanjstva u Babilonu, kamo ih bijaše odveo babilonski kralj Nabukodonozor. Vratili su se u Jeruzalem i Judeju, svaki u svoj grad."},{"v":2,"t":"Stigli su oni i s njima Zerubabel, Ješua, Nehemija, Seraja, Reelaja, Nahamani, Mordokaj, Bilšan, Mispar, Bigvaj, Rehum i Baana. Evo popisa ljudi od naroda Izraelova:"},{"v":3,"t":"sinovi Paroševi: dvije tisuće stotinu sedamdeset i dva;"},{"v":4,"t":"sinovi Šefatjini: tri stotine sedamdeset i dva;"},{"v":5,"t":"Arahovi sinovi: sedam stotina sedamdeset i pet;"},{"v":6,"t":"sinovi Pahat-Moabovi, to jest sinovi Ješuini i Joabovi sinovi: dvije tisuće osam stotina i dvanaest;"},{"v":7,"t":"Elamovi sinovi: tisuću dvije stotine pedeset i četiri;"},{"v":8,"t":"sinovi Zatuovi: devet stotina četrdeset i pet;"},{"v":9,"t":"Zakajevi sinovi: sedam stotina i šezdeset;"},{"v":10,"t":"Banijevi sinovi: šest stotina četrdeset i dva;"},{"v":11,"t":"Bebajevi sinovi: šest stotina dvadeset i tri;"},{"v":12,"t":"sinovi Azgadovi: tisuću dvije stotine dvadeset i dva;"},{"v":13,"t":"Adonikamovi sinovi: šest stotina šezdeset i šest;"},{"v":14,"t":"sinovi Bigvajevi: dvije tisuće pedeset i šest;"},{"v":15,"t":"Adinovi sinovi: četiri stotine pedeset i četiri;"},{"v":16,"t":"sinovi Aterovi, od Ezekije: devedeset i osam;"},{"v":17,"t":"Besajevi sinovi: tri stotine dvadeset i tri;"},{"v":18,"t":"sinovi Jorini: stotinu i dvanaest;"},{"v":19,"t":"Hašumovi sinovi: dvije stotine dvadeset i tri;"},{"v":20,"t":"sinovi Gibarovi: devedeset i pet;"},{"v":21,"t":"ljudi iz Betlehema: stotinu dvadeset i tri;"},{"v":22,"t":"ljudi iz Netofe: pedeset i šest;"},{"v":23,"t":"ljudi iz Anatota: stotinu dvadeset i osam;"},{"v":24,"t":"ljudi iz Bet Azmaveta: četrdeset i dva;"},{"v":25,"t":"ljudi iz Kirjat Jearima, Kefire i Beerota: sedam stotina četrdeset i tri;"},{"v":26,"t":"ljudi iz Rame i Gebe: šest stotina dvadeset i jedan;"},{"v":27,"t":"ljudi iz Mikmasa: stotinu dvadeset i dva;"},{"v":28,"t":"ljudi iz Betela i Aja: dvije stotine dvadeset i tri;"},{"v":29,"t":"nebonski sinovi: pedeset i dva;"},{"v":30,"t":"sinovi Magbiša: stotinu pedeset i šest;"},{"v":31,"t":"sinovi jednoga drugog Elama: tisuću dvije stotine pedeset i četiri;"},{"v":32,"t":"Harimovi sinovi: tri stotine i dvadeset;"},{"v":33,"t":"sinovi Loda, Hadida i Onona: sedam stotina dvadeset i pet;"},{"v":34,"t":"sinovi Jerihona: tri stotine četrdeset i pet;"},{"v":35,"t":"sinovi Senajini: tri tisuće šest stotina trideset."},{"v":36,"t":"Svećenici: Jedajini sinovi, to jest iz kuće Ješuine: devet stotina sedamdeset i tri;"},{"v":37,"t":"sinovi Imerovi: tisuću pedeset i dva;"},{"v":38,"t":"Pašhurovi sinovi: tisuću dvije stotine četrdeset i sedam;"},{"v":39,"t":"sinovi Harimovi: tisuću i sedamnaest."},{"v":40,"t":"Leviti: sinovi Ješuini i Kadmielovi od Hodavjinovaca: sedamdeset i četiri."},{"v":41,"t":"Pjevači: sinovi Asafovi: stotinu dvadeset i osam."},{"v":42,"t":"Vratari: sinovi Šalumovi, sinovi Aterovi, sinovi Talmonovi, sinovi Akubovi, sinovi Hatitini i sinovi Šobajevi: u svemu stotinu trideset i devet."},{"v":43,"t":"Netinci - sluge hramske: Sihini sinovi, sinovi Hasufini, sinovi Tabaotovi,"},{"v":44,"t":"Kerosovi sinovi, Siahini sinovi, Fadonovi sinovi,"},{"v":45,"t":"sinovi Lebanovi, sinovi Hagabini, sinovi Akubovi,"},{"v":46,"t":"Hagabovi sinovi, Šamlajevi sinovi, Hananovi sinovi,"},{"v":47,"t":"sinovi Gidelovi, sinovi Gaharovi, sinovi Reajini,"},{"v":48,"t":"Resinovi sinovi, Nekodini sinovi, Gazamovi sinovi,"},{"v":49,"t":"sinovi Uzini, sinovi Faseahini, sinovi Besajevi,"},{"v":50,"t":"Asnanini sinovi, Meunimovi sinovi, Nefusimovi sinovi,"},{"v":51,"t":"sinovi Bakbukovi, sinovi Hakufini, sinovi Harhurovi,"},{"v":52,"t":"Baslutovi sinovi, Mehidini sinovi, Haršini sinovi,"},{"v":53,"t":"sinovi Barkosovi, sinovi Sisrini, sinovi Tamahovi,"},{"v":54,"t":"Nesiahovi sinovi, Hatifini sinovi."},{"v":55,"t":"Sinovi slugu Salomonovih: sinovi Sotajevi, sinovi Hasoferetovi, sinovi Farudini,"},{"v":56,"t":"Jalini sinovi, Darkonovi sinovi, Gidelovi sinovi,"},{"v":57,"t":"sinovi Šefatjini, sinovi Hatilovi, sinovi Pokeret-Hasebajimovi, sinovi Amijevi."},{"v":58,"t":"Svega netinaca i sinova slugu Salomonovih: tri stotine dvadeset i dva."},{"v":59,"t":"Oni koji su pošli iz Tel Melaha, Tel Harše, Keruba, Adana, Imera, a nisu mogli dokazati da li je njihov dom i njihovo sjeme izraelskog podrijetla:"},{"v":60,"t":"sinovi Dalajini, sinovi Tobijini, sinovi Nekodini - njih šest stotina pedeset i dva."},{"v":61,"t":"A od svećeničkih sinova: Hobajini sinovi, Hakosovi sinovi, sinovi Barzilaja - onoga koji je uzeo za ženu jednu kćer Barzilaja Gileađanina te se prozvao tim imenom."},{"v":62,"t":"Oni su tražili svoje rodoslovne popise, ali ih nisu našli. Bili su izlučeni iz svećeništva."},{"v":63,"t":"I namjesnik im zabrani jesti od svetinja sve dok se ne pojavi svećenik za Urim i Tumim."},{"v":64,"t":"Sav je zbor brojio četrdeset i dvije tisuće tri stotine i šezdeset duša,"},{"v":65,"t":"ne računajući njihove sluge i sluškinje, kojih bijaše sedam tisuća tri stotine i sedam. Bijaše i dvije stotine pjevača i pjevačica."},{"v":66,"t":"Njihovih je konja bilo sedam stotina trideset i šest, njihovih mazga dvije stotine četrdeset i pet,"},{"v":67,"t":"deva je bilo četiri stotine trideset i pet, a njihovih magaraca ukupno šest tisuća sedam stotina i dvadeset."},{"v":68,"t":"Stanovit broj obiteljskih glavara kad su stigli u Dom Jahvin, koji je u Jeruzalemu, dragovoljno su priložili darove za Dom Božji da bi se podigao na svome mjestu."},{"v":69,"t":"Dali su prema svojim mogućnostima u riznicu šezdeset tisuća drahmi zlata, pet tisuća mina srebra i stotinu svećeničkih haljina."},{"v":70,"t":"Svećenici, leviti i dio naroda nastaniše se u Jeruzalemu; a vratari, pjevači, netinci i svi ostali Izraelci u svojim gradovima."}]},"3":{"hr":[{"v":1,"t":"Kad je došao sedmi mjesec - sinovi su Izraelovi bili već u svojim gradovima - sabrao se sav narod kao jedan čovjek u Jeruzalemu."},{"v":2,"t":"Tada Ješua, sin Josadakov, sa svojom braćom svećenicima, i Zerubabel, sin Šealtielov, sa svojom braćom, počeše graditi žrtvenik Bogu Izraelovu da bi prinosili paljenice, kako je pisano u Zakonu Mojsija, čovjeka Božjeg."},{"v":3,"t":"I podigoše žrtvenik na starome mjestu - iako su bili u strahu od naroda u zemlji - i prinosili su paljenice Jahvi, paljenice jutarnje i večernje;"},{"v":4,"t":"i slavili su Blagdan sjenica, kako je pisano: prinosili su svakodnevno broj paljenica propisan za svaki dan."},{"v":5,"t":"Osim toga prinosili su svakidašnje paljenice, zatim žrtve određene za mlađak i za sve blagdane Jahvine i za sve one koji su htjeli dragovoljno žrtvovati Jahvi."},{"v":6,"t":"Od prvoga dana u sedmom mjesecu počeli su prinositi Jahvi žrtve paljenice, premda još nisu bili položeni temelji svetišta Jahvina."},{"v":7,"t":"I dadoše novac kamenarima i drvodjelcima; Sidoncima i Tircima poslaše hranu i piće i ulje da dovezu drva cedrova s Libanona do Jafe po dopuštenju perzijskoga kralja Kira."},{"v":8,"t":"A druge godine poslije njihova dolaska k Domu Božjemu u Jeruzalemu, drugoga mjeseca kako su Zerubabel, sin Šealtielov, i Ješua, sin Josadakov, s ostalom svojom braćom svećenicima, levitima i sa svim narodom koji se iz ropstva vratio u Jeruzalem počeli graditi, postavili su levite od dvadeset godina naviše da upravljaju poslovima oko Doma Jahvina."},{"v":9,"t":"Ješua, njegovi sinovi i braća njegova Kadmiel, Binuj i Hodavja bijahu postavljeni da kao jedan upravljaju poslenicima na gradnji Doma Božjega."},{"v":10,"t":"Kad su zidari bili postavili temelje Svetišta Jahvina, postavili su se svećenici u svečanim odjećama, s trubama, a tako i leviti, sinovi Asafovi, s cimbalima da slave Jahvu prema odredbama Davida, kralja Izraelova."},{"v":11,"t":"I pjevahu Jahvi hvalu i slavu: “Jer je dobar, jer je vječna njegova ljubav prema Izraelu.” I sav je narod klicao hvaleći Jahvu, jer je Dom Jahvin bio postavljen na svoje temelje."},{"v":12,"t":"Zaista, mnogi svećenici, mnogi leviti i glavari obiteljski i starješine, koji su svojim očima vidjeli temelje prijašnjega Hrama, plakahu iza glasa, a mnogi opet snažno klicahu od radosti."},{"v":13,"t":"I tako nitko nije mogao razlikovati radosno klicanje od plača u narodu; jer je narod glasno klicao i vika se čula vrlo daleko."}]},"4":{"hr":[{"v":1,"t":"Ali kada su čuli Judini i Benjaminovi neprijatelji da povratnici iz sužanjstva grade svetište Jahvi, Bogu Izraelovu,"},{"v":2,"t":"potražiše Zerubabela, Ješuu i glavare obiteljske i rekoše im: “Mi želimo s vama graditi, jer, kao i vi, tražimo Boga vašega i njemu prinosimo žrtve od vremena Esar Hadona, asirskoga kralja, koji nas je ovamo doveo.”"},{"v":3,"t":"Zerubabel, Ješua i glavari izraelskih obitelji odgovoriše im: “Nije na vama da s nama gradite Dom našemu Bogu: gradit ćemo mi sami Jahvi, Bogu Izraelovu, kako nam je naredio Kir, kralj perzijski.”"},{"v":4,"t":"Tada je narod one zemlje plašio ljude Judeje i smetao im u gradnji."},{"v":5,"t":"Podmitili su savjetnike da im ometaju naum: tako je bilo za vrijeme perzijskoga kralja Kira sve do perzijskoga kralja Darija. Samarijanske smetnje za Kserksove i Artakserksove vladavine"},{"v":6,"t":"Za Kserksova kraljevanja, na početku njegove vladavine, sastaviše tužbu protiv stanovnika Judeje i Jeruzalema."},{"v":7,"t":"I za vremena Artakserksova pisali su Bišlam, Mitredat, Tabel i ostali njihovi drugovi protiv Jeruzalema perzijskom kralju Artakserksu. Podnesak je bio pisan aramejskim pismom i jezikom."},{"v":8,"t":"Zatim su upravitelj Rehum i tajnik Šimšaj napisali kralju Artakserksu slijedeće pismo protiv Jeruzalema -"},{"v":9,"t":"upravitelj Rehum, tajnik Šimšaj i ostali drugovi njihovi: perzijski suci, poslanici, činovnici; Arkevajci, Babilonci, Suzanci - to jest Elamci -"},{"v":10,"t":"i ostali narodi koje je veliki i slavni Asurbanipal bio odveo u sužanjstvo i naselio ih u gradove Samarije i druge krajeve s onu stranu Rijeke."},{"v":11,"t":"Evo prijepisa pisma koje su mu poslali: “Kralju Artakserksu, tvoje sluge, ljudi s onu stranu Rijeke. Sada, dakle,"},{"v":12,"t":"neka zna kralj da su Judejci stigli k nama od tebe; došavši u Jeruzalem, žele ponovo sagraditi odmetnički i opaki grad; podižu zidine, a temelje su već postavili."},{"v":13,"t":"Neka zna kralj: ako ovaj grad bude sagrađen i zidovi podignuti, neće se više plaćati porez, ni danak, ni carina, i ovaj će grad biti na štetu kraljevske riznice."},{"v":14,"t":"Budući da jedemo dvorsku sol, ne čini nam se doličnim gledati ovu sramotu nanesenu kralju. Zato, dakle, obavještavamo kralja:"},{"v":15,"t":"neka se poduzmu istraživanja u ljetopisima tvojih očeva: u tim ćeš ljetopisima naći i utvrditi da je ovaj grad odmetnički grad, nesretan za kraljeve i pokrajine i da su se u njemu od davnine dizale bune. Zato je ovaj grad bio razoren."},{"v":16,"t":"Obavješćujemo kralja da neće biti više tvoje područje preko Rijeke ako ovaj grad bude ponovo sagrađen i zidovi podignuti!”"},{"v":17,"t":"Kralj je poslao ovaj odgovor: “Rehumu, upravitelju, Šimšaju, tajniku, i ostalim drugovima njihovim koji borave u Samariji i drugdje, s onu stranu Rijeke - mir! Evo,"},{"v":18,"t":"podnesak koji ste mi poslali bio je preda mnom pričitan u njegovu prijevodu."},{"v":19,"t":"Po mojoj su naredbi poduzeli istraživanja i utvrdili da se taj grad dizao od davnine protiv kraljeva i da su u njemu bivali ustanci i bune."},{"v":20,"t":"I moćni su kraljevi kraljevali u Jeruzalemu, koji su gospodarili svime s onu stranu Rijeke: njima se plaćao danak, porez i carina."},{"v":21,"t":"Zapovjedite, dakle, da se prekine pothvat onih ljudi: taj se grad neće zidati dok ja o tome ne odlučim."},{"v":22,"t":"Čuvajte se svakog propusta u postupku, da ne bi zlo poraslo na štetu kraljeva.”"},{"v":23,"t":"Pošto je prijepis otpisa kralja Artakserksa pročitan pred Rehumom, upraviteljem, Šimšajem, tajnikom, i pred njihovim drugovima, oni brzo odoše u Jeruzalem k Judejcima te im oružanom snagom zabraniše radove."},{"v":24,"t":"Tako su obustavljeni poslovi oko gradnje Doma Božjega u Jeruzalemu. Bili su prekinuti sve do druge godine kraljevanja Darija, perzijskoga kralja."}]},"5":{"hr":[{"v":1,"t":"Tada su proroci Hagaj i Zaharija, sin Adonov, počeli prorokovati Judejcima u Judeji i Jeruzalemu, u ime Boga Izraelova, koji je bio nad njima;"},{"v":2,"t":"na to ustadoše Zerubabel, sin Šealtielov, i Ješua, sin Josadakov, i počeše zidati Dom Božji u Jeruzalemu: proroci su Božji bili s ljudima i bodrili ih."},{"v":3,"t":"U to vrijeme dođoše k njima Tatnaj, satrap s onu stranu Rijeke, Šetar Boznaj i drugovi njihovi poslanici i upitaše ih: “Tko vam je dopustio da gradite ovaj hram i da podižete ove zidove?"},{"v":4,"t":"Kako se zovu ljudi koji su sagradili ovu zgradu?”"},{"v":5,"t":"Ali je oko Božje bdjelo nad starješinama judejskim, te im nisu zabranili da rade dok obavijest nije otišla Dariju i stigao o tom pismeni odgovor."},{"v":6,"t":"Ovo je prijepis pisma koje su kralju Dariju poslali Tatnaj, satrap s one strane Rijeke, Šetar Boznaj i njihovi drugovi poslanici s one strane Eufrata."},{"v":7,"t":"Oni su mu uputili izvješće ovog sadržaja: “Kralju Dariju svaki mir!"},{"v":8,"t":"Neka znade kralj da smo došli u pokrajinu Judeju k Domu Boga velikoga: grade ga od krupnog kamenja, drvetom oblažu zidove; posao se brižljivo izvodi i napreduje u njihovim rukama."},{"v":9,"t":"Zapitali smo njihove starješine i rekli smo im: 'Tko vam je dopustio da gradite ovaj hram i da podignete njegove zidove?'"},{"v":10,"t":"Pitali smo ih i za njihova imena da bismo ti javili. Tako smo i zapisali imena onih koji zapovijedaju ljudstvu."},{"v":11,"t":"A oni nam ovako odgovoriše: 'Mi smo sluge Boga neba i zemlje; gradimo Hram koji je bio sagrađen prije mnogo godina i koji je bio sagradio i podigao veliki kralj Izraela."},{"v":12,"t":"Ali kad su naši oci rasrdili Boga neba, on ih je predao u ruke Nabukodonozora Kaldejca, babilonskog kralja, koji je razorio ovaj Hram i odveo narod u sužanjstvo u Babilon."},{"v":13,"t":"Ali prve godine Kira, kralja babilonskog, zapovjedio je kralj Kir da se ponovo sazida ovaj Dom Božji."},{"v":14,"t":"Još i zlatno i srebrno posuđe Doma Božjega, koje Nabukodonozor bijaše odnio iz svetišta u Jeruzalemu i prenio ga u svetište babilonsko, uzeo je kralj Kir iz svetišta u Babilonu i predao čovjeku po imenu Šešbasaru, koga je postavio upraviteljem,"},{"v":15,"t":"i rekao mu je: 'Uzmi ovo posuđe, pođi i metni ga u svetište jeruzalemsko, i neka se Dom Božji zida na svome starom mjestu.'"},{"v":16,"t":"Taj je Šešbasar došao, dakle, i postavio temelje Doma Božjega u Jeruzalemu. I od tada pa do danas gradi se, i još nije dovršen.'"},{"v":17,"t":"Sada, dakle, ako kralj želi, neka se istraži u pismohrani kraljevoj u Babilonu je li zaista kralj Kir izdao zapovijed da se sagradi Dom Božji u Jeruzalemu. A kraljeva odluka o tome neka nam se saopći.”"}]},"6":{"hr":[{"v":1,"t":"Tada, po naredbi kralja Darija, uzeše tražiti u Babilonu, u spremištu gdje je bila pismohrana,"},{"v":2,"t":"i nađoše u Ekbatani, tvrđavi u medijskoj pokrajini, svitak s ovom poveljom: “Na spomen."},{"v":3,"t":"Prve godine kraljevanja Kira proglasio je kralj Kir: Dom Božji u Jeruzalemu. Dom neka se sagradi kao mjesto gdje će se prinositi žrtve i gdje će se donositi prinosi za paljenje. Neka bude visok šezdeset lakata i širok šezdeset lakata."},{"v":4,"t":"Tri reda neka budu od velikog kamenja, a jedan od drveta. Trošak će se podmiriti iz kraljevskog dvora."},{"v":5,"t":"Povrh toga, posuđe zlatno i srebrno iz Doma Božjeg koje Nabukodonozor bijaše uzeo iz svetišta u Jeruzalemu i prenio u Babilon neka se vrati i bude na svome mjestu u svetištu jeruzalemskom i neka se postavi u Domu Božjem.”"},{"v":6,"t":"“Sada, dakle, Tatnaju, satrape s onu stranu Rijeke, Šetar Boznaju i drugovi vaši poslanici s onu stranu Rijeke, udaljite se odatle!"},{"v":7,"t":"Pustite neka taj Dom Božji grade upravitelji i starješine židovske. Dom Božji treba sagraditi na njegovu prvotnom mjestu."},{"v":8,"t":"Evo mojih naredaba o vašem držanju prema starješinama judejskim kako bi se ponovo sagradio taj Dom Božji: od kraljevskog blaga - to jest od danka s onu stranu Rijeke - neka se plaća onim ljudima brižljivo, bez prijekida,"},{"v":9,"t":"i što im bude trebalo za žrtve paljenice Bogu neba: junaca, ovnova i jaganjaca, i pšenice, soli, vina i ulja, neka im se redovito daje svakoga dana, prema uputama svećenika u Jeruzalemu."},{"v":10,"t":"Neka prinose žrtve na ugodan miris Bogu neba, neka mole za život kralja i njegovih sinova."},{"v":11,"t":"Naređujem osim toga: tko god prekrši ovu naredbu, neka mu se izvadi greda iz kuće pa neka na njoj bude pogubljen, a kuća da mu zato postane bunište."},{"v":12,"t":"I Bog, koji je ondje nastanio svoje Ime, neka obori svakog kralja i narod koji bi se drznuo da prekrši moju naredbu i sruši Dom Božji u Jeruzalemu! Ja, Darije, izdao sam ovu zapovijed. Neka se točno vrši!”"},{"v":13,"t":"Tada Tatnaj, satrap s onu stranu Rijeke, Šetar Boznaj i njihovi drugovi učiniše onako kako je zapovjedio kralj Darije."},{"v":14,"t":"A židovske su starješine nastavile uspješno graditi po nadahnuću proroka Hagaja i Zaharije, sina Adonova. Dovršili su gradnju po naredbi Boga Izraelova i po naredbi Kira i Darija i Artakserksa, kralja perzijskoga."},{"v":15,"t":"Hram je zavšen dvadeset i trećeg dana mjeseca Adara. Bilo je to šeste godine vladavine kralja Darija."},{"v":16,"t":"Izraelci - svećenici, leviti i ostatak povratnika iz sužanjstva - radosno posvetiše taj Dom Božji."},{"v":17,"t":"Žrtvovaše za posvećenje Doma Božjega stotinu junaca, dvije stotine ovnova, četiri stotine janjaca i, kao žrtvu za grijehe svega Izraela, dvanaest jaraca - prema broju plemena Izraelovih."},{"v":18,"t":"Zatim postaviše svećenike po njihovim redovima i levite po njihovim razredima za službu Domu Božjem u Jeruzalemu, kako je propisano u knjizi Mojsijevoj."},{"v":19,"t":"Povratnici iz sužanjstva slavili su Pashu četrnaestog dana prvoga mjeseca."},{"v":20,"t":"Svi su se leviti, kao jedan čovjek, očistili: svi su bili čisti; žrtvovali su pashu za sve povratnike iz ropstva, za svoju braću svećenike i za sebe."},{"v":21,"t":"Blagovali su pashu Izraelci koji su se vratili iz ropstva i svi oni koji su im se, prekinuvši s nečistoćom naroda zemlje, pridružili da traže Jahvu, Boga Izraelova."},{"v":22,"t":"I svetkovahu radosno Blagdan beskvasnih hljebova sedam dana: jer ih je Jahve ispunio radošću i obratio prema njima srce asirskog kralja da ojača njihove ruke u radovima oko Doma Boga, Boga Izraelova."}]},"7":{"hr":[{"v":1,"t":"Poslije tih događaja, za kraljevanja Artakserksa, kralja perzijskoga, Ezra - sin Seraje, sina Azarje, sina Hilkije,"},{"v":2,"t":"sina Šaluma, sina Sadoka, sina Ahituba,"},{"v":3,"t":"sina Amarje, sina Azarje, sina Merajota,"},{"v":4,"t":"sina Zerahje, sina Uzije, sina Bukija,"},{"v":5,"t":"sina Abišue, sina Pinhasa, sina Eleazara, sina vrhovnog svećenika Arona -"},{"v":6,"t":"taj Ezra vrati se iz Babilona. Bio je književnik vješt Mojsijevu Zakonu, koji je dao Jahve, Bog Izraelov. Kako je ruka Jahve, Boga njegova, bila nad njim, kralj mu je dao sve što je tražio."},{"v":7,"t":"Stanovit broj Izraelaca, svećenika, levita, pjevača, vratara i sluga krenuše u Jeruzalem sedme godine kralja Artakserksa."},{"v":8,"t":"A Ezra je došao u Jeruzalem petoga mjeseca: bilo je to sedme godine kraljeve."},{"v":9,"t":"Pošao je iz Babilona prvoga dana prvoga mjeseca, a stigao je u Jeruzalem prvoga dana petoga mjeseca: nad njim je bila blaga ruka Boga njegova!"},{"v":10,"t":"Jer je Ezra nastojao svim srcem proniknuti Zakon Jahvin, vršiti ga i poučavati Izraela u zakonima i običajima."},{"v":11,"t":"Evo prijepisa isprave koju je kralj Artakserkso dao svećeniku Ezri, književniku vještu naredbama i zakonima što ih je Jahve dao Izraelu:"},{"v":12,"t":"“Artakserkso, kralj kraljeva, svećeniku Ezri, pisaru Zakona Boga nebeskoga, potpuni mir."},{"v":13,"t":"Evo mojih zapovijedi: Tko god u mome kraljevstvu od naroda izraelskog, njegovih svećenika ili od njegovih levita želi poći u Jeruzalem, može ići s tobom."},{"v":14,"t":"Osim toga, šalje te kralj i njegovih sedam savjetnika da pregledaš Judeju i Jeruzalem prema Zakonu Boga tvoga, koji ti je u ruci,"},{"v":15,"t":"i da odneseš srebro i zlato koje kralj i njegovih sedam savjetnika dragovoljno prinose Bogu Izraelovu, koji prebiva u Jeruzalemu,"},{"v":16,"t":"i sve srebro i zlato koje skupiš po svoj pokrajini babilonskoj s dragovoljnim prinosima koje narod i svećenici prinesu za Dom svoga Boga u Jeruzalemu."},{"v":17,"t":"I pobrini se da tim novcem kupiš junaca, ovnova i jaganjaca, a tako i darova i naljeva koji uz to idu: to prinesi na žrtvenik Doma Boga vašega u Jeruzalemu."},{"v":18,"t":"Sa srebrom i zlatom što preostane učinite ti i tvoja braća kako vam se bude najviše svidjelo, vršeći volju Boga vašega."},{"v":19,"t":"Posuđe koje si primio za službu Domu Boga tvoga ostavi pred Bogom tvojim, u Jeruzalemu."},{"v":20,"t":"I što bi još trebalo za Dom Boga tvoga i što bi trebalo nabaviti primit ćeš iz kraljevskih riznica."},{"v":21,"t":"Ja, kralj Artakserkso, još zapovijedam svim rizničarima s one strane Rijeke: sve što od vas zatraži svećenik Ezra, pisar Zakona Boga nebeskoga, podajte odmah najtočnije,"},{"v":22,"t":"do stotinu talenata srebra, stotinu kora pšenice, do stotinu bata vina, do stotinu bata ulja, a soli po želji."},{"v":23,"t":"Sve što naredi Bog nebeski, neka se odmah izvrši u svoj gorljivosti za Dom Boga nebeskog, da gnjev njegov ne dođe na kraljevstvo kraljevo i na djecu njegovu."},{"v":24,"t":"I još vam javljamo da se ne smije udariti danak, ni porez, ni carina ni na jednoga od svećenika, levita, pjevača, netinaca i drugih službenika toga Doma Božjega."},{"v":25,"t":"A ti, Ezra, po mudrosti Boga svoga koju imaš u rukama, postavi činovnike i suce koji će suditi svemu narodu s onu stranu Rijeke, to jest svima koji poznaju Zakon Boga tvoga. Tko ne zna, vi ga poučite."},{"v":26,"t":"Tko ne bude držao Zakona Boga tvojega - koji je i kraljev zakon - neka se oštro osudi: na smrt, na progonstvo, na novčanu globu ili na tamnicu.”"},{"v":27,"t":"“Blagoslovljen neka je Jahve, Bog otaca naših, koji je nadahnuo srce kraljevo da proslavi Dom Jahvin u Jeruzalemu"},{"v":28,"t":"i koji je okrenuo prema meni naklonost kralja, njegovih savjetnika i svih najmoćnijih kraljevskih činovnika. A ja se osmjelih jer ruka Jahve, Boga mojega, bijaše nada mnom i sabrah glavare Izraela da pođu sa mnom.”"}]},"8":{"hr":[{"v":1,"t":"Evo glavara obitelji s rodoslovljem koji su sa mnom pošli iz Babilona za vladavine kralja Artakserksa:"},{"v":2,"t":"Od Pinhasovih sinova: Geršom; od Itamarovih sinova: Daniel; od Davidovih sinova: Hatuš,"},{"v":3,"t":"Šekanijini sinovi; od sinova Paroševih: Zaharija i s njim upisanih muškaraca stotinu i pedeset;"},{"v":4,"t":"od Pahat-Moabovih sinova: Elijoenaj, sin Zerahjin, i s njim dvije stotine muškaraca;"},{"v":5,"t":"od Zatuovih sinova: Šekanija, sin Jahazielov, i s njim tri stotine muškaraca;"},{"v":6,"t":"od sinova Adinovih: Ebed, sin Jonatanov, i s njim pedeset muškaraca;"},{"v":7,"t":"od Elamovih sinova: Izaija, sin Atalijin, i s njim sedamdeset muškaraca;"},{"v":8,"t":"od Šefatjinih sinova: Zebadja, sin Mihaelov, i s njim osamdeset muškaraca;"},{"v":9,"t":"od Joabovih sinova: Obadja, sin Jehielov, i s njim dvije stotine i osamnaest muškaraca;"},{"v":10,"t":"od sinova Banijevih: Šelomit, sin Josifjin, i s njim stotinu i šezdeset muškaraca;"},{"v":11,"t":"od Bebajevih sinova: Zaharija, sin Bebajev, i s njim dvadeset i osam muškaraca;"},{"v":12,"t":"od Azgadovih sinova: Johanan, sin Hakatanov, i s njim stotinu i deset muškaraca;"},{"v":13,"t":"od posljednjih Adonikamovih sinova poimence: Elifelet, Jeiel i Šemaja, i s njima šezdeset muškaraca;"},{"v":14,"t":"i od sinova Bigvajevih: Utaj, sin Zabudov, i s njim sedamdeset muškaraca."},{"v":15,"t":"Sabrao sam ih kod rijeke koja teče prema Ahavi. Utaborili smo se za tri dana ondje. Pregledao sam svjetovnjake i svećenike, ali nisam ondje našao ni jednog levita."},{"v":16,"t":"Tada sam poslao glavare Eliezera, Ariela, Šemaju, Elnatana, Jariba, Elnatana, Natana, Zahariju, Mešulama i učitelje Jojariba i Elnatana"},{"v":17,"t":"i uputio sam ih Idonu, poglavaru mjesta Kasifje. Stavio sam u njihova usta riječi koje će reći Idonu i njegovoj braći koja su se nalazila u mjestu Kasifji da nam pribave sluge za Dom Boga našega."},{"v":18,"t":"Milostiva ruka Boga našega bijaše nad nama i oni nam dovedoše razumna čovjeka između sinova Mahlija, sina Levijeva, sina Izraelova: Šerebju s njegovim sinovima i braćom - njih osamnaest."},{"v":19,"t":"Još Hašabju i s njim njegova brata Izaiju, sina Merarijeva, i njihove sinove: njih dvadeset."},{"v":20,"t":"A od poslužitelja koje su David i glavari postavili levitima da im služe: dvije stotine i dvadeset poslužitelja. Svi su bili poimence zabilježeni."},{"v":21,"t":"Ja sam ondje, kraj rijeke Ahave, proglasio post: da bismo se ponizili pred Bogom svojim i od njega izmolili sretan put sebi, svojoj djeci i svemu blagu svojem."},{"v":22,"t":"Jer bih se stidio moliti od kralja vojske i konjanika da nas štite putem od neprijatelja; izjavili smo, naprotiv, kralju: “Ruka je Boga našega ispružena da blagoslovi sve one koji ga traže; njegova snaga i gnjev njegov nad onima su koji ga ostavljaju.”"},{"v":23,"t":"I tako smo postili i molili Boga svoga na ovu nakanu, i on nas usliša."},{"v":24,"t":"Izabrao sam dvanaest glavara svećeničkih, Šerebju i Hašabju, i s njima desetoricu njihove braće;"},{"v":25,"t":"izmjerih im srebro, zlato i posuđe, darove koje su kralj, njegovi savjetnici, velikaši i svi Izraelci darovali za Dom Boga našega."},{"v":26,"t":"Izmjerih i stavih u njihove ruke šest stotina i pedeset talenata srebra, stotinu srebrnih posuda od po dva talenta, stotinu talenata zlata,"},{"v":27,"t":"dvadeset zlatnih čaša od tisuću darika i dva vrča od dobre pozlaćene mjedi, skupocjene kao zlato."},{"v":28,"t":"I rekoh im: “Vi ste Jahvi posvećeni; ovo je posuđe posvećeno, ovo srebro i zlato dragovoljno je darovano Jahvi, Bogu otaca vaših."},{"v":29,"t":"Pazite i čuvajte ovo sve dok ne izmjerite pred glavarima svećeničkim i pred levitima i glavarima obitelji Izraelovih u Jeruzalemu, u dvoranama Doma Jahvina.”"},{"v":30,"t":"Svećenici i leviti primiše, dakle, izmjereno srebro, zlato i posuđe da ga odnesu u Jeruzalem, u Dom Boga našega."},{"v":31,"t":"Dvanaestog dana prvoga mjeseca krenusmo od rijeke Ahave da pođemo u Jeruzalem: ruka Boga našega bijaše nad nama; on nas je na putu štitio od napada neprijatelja i od pljačkaša."},{"v":32,"t":"Stigli smo u Jeruzalem i ondje smo se tri dana odmarali."},{"v":33,"t":"Četvrtoga dana izmjereno je srebro, zlato i posuđe u Domu Boga našega i predano je u ruke Merimotu, sinu Urijinu, s kojim je bio Eleazar, sin Pinhasov; a pred njima bijahu leviti: Jozabad, sin Ješuin, i Noadja, sin Binujev."},{"v":34,"t":"Sve je bilo na broju i težini. Zabilježena je tada sveukupna težina. U to vrijeme"},{"v":35,"t":"oni koji su se vratili iz sužanjstva, povratnici, priniješe žrtvu paljenicu Bogu Izraelovu: dvanaest junaca za sav Izrael, devedeset i šest ovnova, sedamdeset i sedam janjaca, dvanaest jaraca za grijehe - sve to kao paljenicu Jahvi."},{"v":36,"t":"Zatim predaše kraljeve naredbe kraljevskim satrapima i upraviteljima s one strane Rijeke i oni pomogoše narod i Dom Božji."}]},"9":{"hr":[{"v":1,"t":"Pošto je sve to uređeno, dođoše mi glavari govoreći: “Izraelski narod, svećenici i leviti nisu se odvojili od naroda zemlje, okorjelih u njihovim gnusobama: nisu se odijelili od Kanaanaca, Hetita, Perižana, Jebusejaca, Amonaca, Moabaca, Egipćana i Amorejaca,"},{"v":2,"t":"nego su za sebe i za sinove svoje uzimali za žene njihove kćeri: sveti rod pomiješao se s narodima zemlje; glavari i savjetnici prvi su počinili tu nevjernost.”"},{"v":3,"t":"Na tu vijest razderah svoju odjeću i svoj ogrtač, čupao sam kosu i bradu svoju i sjedoh utučen."},{"v":4,"t":"Svi koji su strahovali od riječi Božje sakupili se oko mene zbog nevjernosti onih povratnika. A ja sam sveudilj sjedio utučen, sve do večernje žrtve."},{"v":5,"t":"A o večernjoj žrtvi trgnuh se iz svoga jada i, razderane odjeće i ogrtača, padoh na koljena, raširih ruke prema Jahvi, Bogu svome,"},{"v":6,"t":"i rekoh: “Bože moj! Stid me i bojim se podići svoje lice k tebi, Bože moj! Jer su se umnožila zlodjela naša preko glave i grijesi su se naši nagomilali do neba."},{"v":7,"t":"Od vremena otaca svojih pa do danas u krivnji smo velikoj i zbog zlodjela svojih bijasmo predani u ruke zemaljskih kraljeva: mi, kraljevi naši i svećenici naši - pod mač, u sužanjstvo, u plijen i na sramotu, kao što je to i danas."},{"v":8,"t":"Ali sada, za kratko vrijeme, učinio nam je Jahve, Bog naš, milost i ostavi nam Ostatak i dade nam utočište u svome svetom mjestu: tako nam je Bog naš prosvijetlio oči i dao nam malo života u robovanju našem."},{"v":9,"t":"Jer mi smo robovi, ali nas u ropstvu našem nije nikada ostavio Bog naš: nego nam dade te nađosmo milost u perzijskih kraljeva, dade nam snage da podignemo Dom Boga našega i da obnovimo njegove ruševine i pribavi nam utočište u Judeji i Jeruzalemu."},{"v":10,"t":"Ali sada, što možemo reći, Bože moj, kad smo poslije svega toga odnemarili zapovijedi tvoje"},{"v":11,"t":"koje si zapovjedio preko svojih slugu proroka ovim riječima: 'Zemlja u koju ulazite da je zaposjednete nečista je zemlja od nečistoće naroda zemlje, od gnusoba njihovih kojima su se napunili od jednoga kraja do drugoga."},{"v":12,"t":"Stoga ne dajite kćeri svojih za njihove sinove i ne uzimajte njihovih kćeri za svoje sinove, ne želite nikakav njihov mir i sreću njihovu, da biste postali snažni i jeli najbolje plodove zemlje i ostavili je zauvijek u nasljedstvo sinovima svojim.'"},{"v":13,"t":"I poslije svega što nas je stiglo zbog zlih djela naših i zbog naše velike krivice, dobro je, o Bože naš, što si naša zlodjela smatrao manjima nego što je zloća njihova i što si nam ostavio ovaj Ostatak!"},{"v":14,"t":"Zar možemo i dalje kršiti naredbe tvoje i vezivati se s ovim gnusnim narodima? Ne bi li se ti razgnjevio i satro nas da ni Ostatka ni ikoga spašena više ne bi bilo?"},{"v":15,"t":"Jahve, Bože Izraelov, po pravednosti tvojoj mi ostadosmo Ostatak, kao što smo danas: evo nas pred tobom s grijehom svojim! Zaista ne bismo zbog njega smjeli stajati pred tobom!”"}]},"10":{"hr":[{"v":1,"t":"Dok je Ezra molio i priznavao grijehe, plačući i ležeći pred Domom Božjim, skupilo se oko njega mnoštvo Izraelaca, ljudi, žena i djece: i taj je narod gorko plakao."},{"v":2,"t":"Tada Šekanija, sin Jehielov, jedan od sinova Elamovih, uzimajući riječ reče Ezri: “Mi smo izdali Boga svoga ženeći se tuđinkama iz naroda zemlje. Ali još ima nade Izraelu."},{"v":3,"t":"Obnovimo sada Savez s Bogom svojim: obećajmo da ćemo, prema savjetu moga gospodara i onih koji osjećaju strahopočitanje prema zapovijedi Boga našega, otpustiti svoje žene tuđinke i djecu koju su rodile. Učinimo dakle po Zakonu!"},{"v":4,"t":"Ustani, jer to je tvoja dužnost, a mi ćemo biti uza te. Budi hrabar i na djelo!”"},{"v":5,"t":"Tada ustade Ezra i zakle glavare svećeničke, i levite, i sve Izraelce da će učiniti kako im bijaše rekao. I zakleše se."},{"v":6,"t":"Ezra se udalji ispred Doma Božjega i uđe u dvoranu Johanana, sina Elijašibova. Ondje provede noć i nije jeo ni kruha niti je pio vode jer tugovaše zbog nevjernosti povratnika."},{"v":7,"t":"Zatim je objavljeno u Judeji i Jeruzalemu svima povratnicima da se skupe u Jeruzalemu:"},{"v":8,"t":"a tko ne bude došao u Jeruzalem za tri dana, toga će pozvati glavari i starješine, bit će mu zaplijenjeno imanje i isključit će ga iz zbora povratnika."},{"v":9,"t":"Svi su se ljudi od Jude i Benjamina sakupili tako za tri dana u Jeruzalemu. Bilo je to devetoga mjeseca, dvadesetoga dana u mjesecu. Sav se narod smjestio na trgu pred Domom Božjim, dršćući zbog svega toga i zbog jake kiše."},{"v":10,"t":"Tada, ustavši, svećenik Ezra reče im: “Vi ste se iznevjerili kad ste se oženili tuđinkama. Tako ste povećali grijeh Izraelov!"},{"v":11,"t":"Ali podajte sada hvalu Jahvi, Bogu otaca svojih, i izvršite volju njegovu te se rastavite od naroda zemlje i od žena tuđinki.”"},{"v":12,"t":"Sav je zbor odgovorio snažnim glasom: “Jest, dužnost nam je učiniti po tvome savjetu!"},{"v":13,"t":"Ali naroda ima mnogo i dažd nahodi: vani se ne može stajati. Osim toga, nije to posao od dan-dva, jer nas je mnogo koji smo u tome sagriješili."},{"v":14,"t":"Mogu nas na zajedničkom zboru zastupati naši glavari: svi koji su po našim gradovima oženjeni tuđinkama mogu doći u određeno vrijeme u pratnji starješina i sudaca svakoga grada, sve dok ne budemo odvratili gnjev Boga svojega zbog ovoga.”"},{"v":15,"t":"Samo Jonatan, sin Asahelov, i Jahzija, sin Tikvin, bijahu se usprotivili; a podupirahu ih Mešulam i levit Šabetaj."},{"v":16,"t":"Povratnici učiniše tako: rastaše se. Svećenik Ezra izabra za pomoćnike glavare obitelji, prema njihovim domovima, i svi su bili poimence određeni. Počeli su zasjedati prvoga dana desetoga mjeseca da bi sve ispitali."},{"v":17,"t":"I prvoga dana prvoga mjeseca završiše sa svima koji se bijahu oženili tuđinkama."},{"v":18,"t":"Među pripadnicima svećenstva evo koji bijahu oženjeni tuđinkama: između sinova Ješue, sina Josadakova, i među njegovom braćom: Maaseja, Eliezer, Jarib i Gedalija;"},{"v":19,"t":"oni dadoše svoju ruku da će otpustiti svoje žene i da će za svoj grijeh prinijeti ovna kao naknadnicu."},{"v":20,"t":"Od sinova Imerovih: Hanani i Zebadja;"},{"v":21,"t":"od Harimovih sinova: Maaseja, Ilija, Šemaja, Jehiel i Uzija;"},{"v":22,"t":"od Pašhurovih sinova: Elijoenaj, Maaseja, Jišmael, Netanel, Jozabad i Elasa."},{"v":23,"t":"Od levita: Jozabad, Šimej, Kelaja - nazvan Kelita - Petahja, Juda i Eliezer."},{"v":24,"t":"Od pjevača: Elijašib i Zakur. Od vratara: Šalum, Telem i Uri."},{"v":25,"t":"A između Izraelaca: od sinova Paroševih: Ramja, Jizija, Malkija, Mijamin, Eleazar, Malkija i Benaja;"},{"v":26,"t":"od sinova Elamovih: Matanija, Zaharija, Jehiel, Abdi, Jeremot i Ilija;"},{"v":27,"t":"od sinova Zatuovih: Elijoenaj, Elijašib, Matanija, Jeremot, Zabad i Aziza;"},{"v":28,"t":"od sinova Bebajevih: Johanan, Hananija, Zabaj i Atlaj;"},{"v":29,"t":"od Banijevih sinova: Mešulam, Maluk, Adaja, Jašub, Šeal i Ramot;"},{"v":30,"t":"od Pahat-Moabovih sinova: Adna, Kelal, Benaja, Maaseja, Matanija, Besalel, Binuj i Manaše;"},{"v":31,"t":"od sinova Harimovih: Eliezer, Jišija, Malkija, Šemaja, Šimun,"},{"v":32,"t":"Benjamin, Maluk, Semarja;"},{"v":33,"t":"od sinova Hašumovih: Matnaj, Matata, Zabad, Elifelet, Jeremaj, Manaše, Šimej;"},{"v":34,"t":"od sinova Banijevih: Maadaj, Amram, Joel,"},{"v":35,"t":"Benaja, Bedja, Kelu,"},{"v":36,"t":"Vanija, Meremot, Elijašib,"},{"v":37,"t":"Matanija, Matnaj i Jaasaj;"},{"v":38,"t":"od sinova Binujevih: Šimej,"},{"v":39,"t":"Šelemja, Natan i Adaja;"},{"v":40,"t":"od Zakajevih sinova: Šašaj, Šaraj,"},{"v":41,"t":"Azareel, Šelemja, Šemarja,"},{"v":42,"t":"Šalum, Amarja, Josip;"},{"v":43,"t":"od Nebovih sinova: Jeiel, Matitja, Zabad, Zebina, Jadaj, Joel, Benaja."},{"v":44,"t":"Svi su ovi bili oženjeni tuđinkama, ali su ih otpustili, žene i djecu."}]}},"NEH":{"1":{"hr":[{"v":1,"t":"Povijest Nehemije, sina Hakalijina. Mjeseca Kisleva, dvadesete godine, kad sam bio u Susi,"},{"v":2,"t":"dođe Hanani, jedan od moje braće, s nekim ljudima iz Judeje. Ja ih zapitah o Židovima - o Ostatku što se spasio od sužanjstva i o Jeruzalemu."},{"v":3,"t":"Oni mi odgovoriše: “Ostatak, oni koji su nakon sužanjstva ostali u zemlji, u velikoj su nevolji i sramoti. Jeruzalemski je zid sav razoren, a vrata mu ognjem spaljena.”"},{"v":4,"t":"Kad sam čuo te vijesti, sjedoh i zaplakah. Tugovao sam više dana, postio i molio se pred Bogom nebeskim."},{"v":5,"t":"I rekoh: “O, Jahve, Bože nebeski, veliki i strašni Bože koji čuvaš Savez i naklonost onima koji te ljube i drže zapovijedi tvoje!"},{"v":6,"t":"Neka uho tvoje bude pažljivo i oči tvoje otvorene da čuješ molitvu sluge svoga. Molim ti se sada, danju i noću, za sinove Izraelove, sluge tvoje, i ispovijedam grijehe sinova Izraelovih koje smo učinili protiv tebe; sagriješili smo i ja i kuća oca mojega!"},{"v":7,"t":"Veoma smo zlo činili prema tebi, ne držeći naredaba tvojih, zakona i običaja koje si ti naredio po Mojsiju, sluzi svome."},{"v":8,"t":"Ali se opomeni riječi koje si povjerio Mojsiju, sluzi svome: 'Ako budete nevjerni, ja ću vas rasuti među narode;"},{"v":9,"t":"ali ako se obratite meni i budete poštovali moje naredbe i držali ih, budu li neki od vas prognani i nakraj neba, ja ću vas sakupiti i odvesti na mjesto koje sam izabrao da ondje prebiva moje Ime.'"},{"v":10,"t":"A, eto, oni su tvoje sluge i tvoj narod, koji si izbavio svojom velikom moći i snažnom rukom svojom."},{"v":11,"t":"Ah, Gospode, neka uho tvoje bude pažljivo na molitvu sluge tvoga, na molitvu slugu tvojih, koji su spremni bojati se tvoga Imena. Smjerno te molim, udijeli danas sreću sluzi svome i učini da nađe milost pred ovim čovjekom.” A ja bijah tada peharnik kraljev."}]},"2":{"hr":[{"v":1,"t":"Mjeseca Nisana, dvadesete godine kraljevanja Artakserksova, stajalo je vino pred kraljem. Uzeh ga i ponudih kralju. Nikada pred njim nisam bio tužan."},{"v":2,"t":"Tada mi kralj reče: “Što ti je tužno lice? Nisi li možda bolestan? Nije drugo nego je tuga u tvome srcu!” Ja se veoma uplaših"},{"v":3,"t":"i rekoh kralju: “Neka uvijek živi kralj! Kako mi lice ne bi bilo tužno kad je grad gdje su grobovi mojih otaca razoren, a vrata mu ognjem spaljena?”"},{"v":4,"t":"Kralj me upita: “Što, dakle, želiš?” Zazvah Boga nebeskoga"},{"v":5,"t":"i odgovorih kralju: “Ako je kralju po volji i ako ti je mio sluga tvoj, pusti me da odem u Judeju, u grad grobova mojih otaca, da ga obnovim.”"},{"v":6,"t":"Kralj me upita pred kraljicom, koja je sjedila kraj njega: “Koliko bi trajao tvoj put? Kada ćeš se vratiti?” Pošto sam utvrdio vrijeme koje je odgovaralo kralju, pusti me da odem."},{"v":7,"t":"Još rekoh kralju: “Ako je kralju po volji, mogao bih ponijeti pisma upraviteljima s onu stranu Rijeke da me propuste do Judeje;"},{"v":8,"t":"i pismo Asafu, nadgledniku kraljeve šume, da mi dadne drva za gradnju vrata na tvrđi Hrama, za gradski bedem i za kuću u kojoj ću se nastaniti.” I dade mi kralj, jer dobrostiva ruka Boga moga bijaše nada mnom."},{"v":9,"t":"I dođoh tako k upraviteljima s onu stranu Rijeke i dadoh im kraljeva pisma. A kralj posla sa mnom časnike i konjanike."},{"v":10,"t":"Kad to ču Sanbalat, Horonac, i sluga Tobija, Amonac, bi im vrlo mrsko što je došao čovjek da se zauzme za dobro Izraelaca."},{"v":11,"t":"Stigavši u Jeruzalem, ostadoh ondje tri dana."},{"v":12,"t":"Zatim ustah noću, u pratnji nekoliko ljudi, nikomu ne povjerivši što mi je Bog moj nadahnuo da učinim za Jeruzalem; a nisam imao druge životinje osim kljuseta na kojem sam jahao."},{"v":13,"t":"Iziđoh, dakle, noću na Dolinska vrata i uputih se Zmajevskom izvoru, a zatim prema Smetlišnim vratima: razgledao sam jeruzalemski zid gdje je bio razoren i vrata koja su bila spaljena."},{"v":14,"t":"Nastavio sam put prema Izvorskim vratima i Kraljevskom ribnjaku, ali nisam našao prolaza za životinju na kojoj sam jahao."},{"v":15,"t":"Uspeo sam se zato noću uz Potok, i dalje razgledajući zid, i ponovo sam ušao na Dolinska vrata. Tako sam se vratio,"},{"v":16,"t":"a da savjetnici nisu primijetili kamo sam otišao i što sam učinio. Sve do sada nisam ništa rekao Židovima: ni svećenicima, ni velikašima, ni savjetnicima, ni drugima nadstojnicima."},{"v":17,"t":"Tada im rekoh: “Vidite u kakvoj smo nevolji: Jeruzalem je u ruševinama, a vrata mu spaljena. Hajte, sagradimo jeruzalemski zid da više ne budemo izloženi ruglu.”"},{"v":18,"t":"I objasnih im kako je dobrostiva ruka Boga moga bila nada mnom, a saopćih im i riječi koje mi kralj bijaše rekao. “Ustanimo”, povikaše oni, “i gradimo!” I ukrijepiše im se ruke na dobro djelo."},{"v":19,"t":"Na te vijesti počeše nam se rugati Sanbalat, Horonac, i sluga Tobija, Amonac, i Gešem, Arapin. Prezirno su nam govorili: “Što radite ovdje? Hoćete li se pobuniti protiv kralja?”"},{"v":20,"t":"Ali im ja odgovorih ovim riječima: “Nebeski će nam Bog dati da uspijemo. Mi, sluge njegove, ustasmo da gradimo. A vi nemate ni dijela, ni prava, ni spomena u Jeruzalemu.”"}]},"3":{"hr":[{"v":1,"t":"Tada usta veliki svećenik Elijašib sa svojom braćom svećenicima te sagradiše Ovčja vrata. Posvetiše ih, postaviše im krila i nastaviše graditi sve do kule Meaha i do Hananelove kule."},{"v":2,"t":"Kraj njih su gradili Jerihonci, a do njih je gradio Zakur, sin Imrijev."},{"v":3,"t":"Sinovi Hasnaini gradili su Riblja vrata, stavili dovratke, utvrdili krila, stožere i prijevornice."},{"v":4,"t":"Kraj njih je popravljao Merimot, sin Urije, sina Hakosova; a do njega je popravljao Mešulam, sin Berekje, sina Mešezabelova; a do njega je popravljao Sadok, sin Baanin."},{"v":5,"t":"Kraj njih su popravljali Tekoanci, ali su njihovi plemenitaši odbili da prignu šiju na službu svojim gospodarima."},{"v":6,"t":"Stara vrata popravljali su Jojada, sin Paseahov, i Mešulam, sin Besodjin. Oni su stavili dovratke, učvrstili krila, stožere i prijevornice."},{"v":7,"t":"A kraj njih obnavljahu Melatja Gibeonjanin, Jadon Meronoćanin i ljudi iz Gibeona i Mispe, podložnici upravitelja s onu stranu Rijeke."},{"v":8,"t":"A do njih je popravljao Uziel, Harhajin sin, zlatar, a do njega je popravljao Hananija, jedan od pomastara: oni su utvrdili Jeruzalem sve do Širokog zida."},{"v":9,"t":"Do njih je popravljao Refaja, sin Hurov, glavar polovice jeruzalemskog okruga."},{"v":10,"t":"A do njega je popravljao Jedaja, sin Harumafov, pred svojom kućom; a do njega je popravljao Hatuš, sin Hašabnejin."},{"v":11,"t":"Malkija, sin Harimov, i Hašub, sin Pahat-Moabov, popravljali su dio sve do Pećne kule."},{"v":12,"t":"A do njih je popravljao Šalum, sin Halohešov, glavar polovice okruga, on i njegovi sinovi."},{"v":13,"t":"Dolinska vrata popravljao je Hanum i stanovnici Zanoaha: sagradili su ih, učvrstili krila, stožere i prijevornice i postavili tisuću lakata zida do Smetlišnih vrata."},{"v":14,"t":"Smetlišna vrata popravljao je Malkija, sin Rekabov, glavar bethakeremskog okruga, sa svojim sinovima: učvrstili su krila, stožere i prijevornice."},{"v":15,"t":"Izvorska vrata popravljao je Šalum, sin Kol-Hozeov, glavar nad mispanskim okrugom: sagradio ih je, pokrio ih, utvrdio vratna krila, stožere i prijevornice. On je popravio i zid kod ribnjaka Šiloaha, koji se proteže od Kraljevskog vrta do stepenica što silaze iz Davidova grada."},{"v":16,"t":"Za njim je popravljao Nehemija, sin Azbukov, glavar nad polovicom betsurskog okruga, sve do nasuprot Davidovim grobnicama i do umjetnog ribnjaka i Vojarne."},{"v":17,"t":"Za njim su popravljali leviti: Rehum, sin Banijev; a do njega je popravljao Hašabja, glavar nad polovicom keilskog okruga, za svoje područje."},{"v":18,"t":"Do njih su popravljala njihova braća: Bavaj, sin Henadadov, glavar nad polovicom keilskog kotara;"},{"v":19,"t":"a do njega Ezer, sin Ješuin, glavar Mispe, popravljao je drugi dio, sučelice usponu prema Oružarnici na uglu."},{"v":20,"t":"Za njim je popravljao Baruk, sin Zabajev, i popravio je drugi dio, od ugla do kućnih vrata velikog svećenika Elijašiba."},{"v":21,"t":"Za njim je popravljao Meremot, sin Urije, sina Hakosova, drugi dio: od Elijašibova kućnog ulaza do kraja Elijašibove kuće."},{"v":22,"t":"Za njima su radili na popravcima svećenici koji su živjeli u Okružju."},{"v":23,"t":"Za njima su pak popravljali Benjamin i Hašub sučelice svojim kućama. Za njima je popravljao Azarja, sin Ananijina sina Maaseje, nasuprot svojoj kući."},{"v":24,"t":"Za njima je popravljao Binuj, sin Henadadov, drugi dio - od Azarjine kuće do ugla, do zidnog kruništa."},{"v":25,"t":"Palal, sin Uzajev, popravljao je nasuprot uglu i kuli koja se uzdiže iznad Gornje kraljevske palače, a nalazi se prema dvorištu Tamnice. Za njim je Pedaja, sin Parošev, popravljao"},{"v":26,"t":"sve do Vodenih vrata, u smjeru istoka, i sve do pred Uzdignutu kulu."},{"v":27,"t":"Za njima su popravljali Tekoanci drugi dio nasuprot velikoj Uzdignutoj kuli, sve do Ofelskog zida."},{"v":28,"t":"Od Konjskih vrata popravljali su svećenici, svaki nasuprot svojoj kući."},{"v":29,"t":"Za njima je Sadok, sin Imerov, popravljao nasuprot svojoj kući. Za njim je popravljao Šemaja, sin Šekanijin, čuvar Istočnih vrata."},{"v":30,"t":"Za njim su Hananija, sin Šelemjin, i Hanun, šesti sin Salafov, popravljali drugi dio. Za njima je popravljao Mešulam, sin Berekjin, nasuprot svome stanu."},{"v":31,"t":"Za njim je Malkija, zlatar, popravljao sve do prebivališta netinaca i trgovaca, nasuprot Nadgledničkim vratima do Gornje dvorane na zidnom kruništu."},{"v":32,"t":"A zlatari su i trgovci popravljali između Gornje dvorane na zidnom kruništu do Ovčjih vrata."},{"v":33,"t":"Kad je Sanbalat čuo da gradimo zid, razljutio se. Bio je veoma srdit, ismijavao je Židove"},{"v":34,"t":"i vikao je pred svojom braćom i samarijanskom vojskom: “Što poduzimaju ovi jadni Židovi? Kane li možda popraviti, žrtvovati i završiti sve u jedan dan? Zar će iz hrpe praha dozvati u život spaljeno kamenje?”"},{"v":35,"t":"Tobija, Amonac, koji je bio uz njega, reče: “Neka samo grade! Ali popne li se lisica, srušit će im kamene zidove.”"},{"v":36,"t":"Čuj, o Bože naš, kako nas preziru! Navrni njihove poruge na njihovu glavu. Predaj ih kao plijen u zemlju ropstva."},{"v":37,"t":"Ne pokrivaj njihova bezakonja i grijeh njihov neka ne bude izbrisan pred licem tvojim jer su se rugali graditeljima."},{"v":38,"t":"Tako smo gradili zid, koji je uskoro bio završen do pola visine. Narod je imao oduševljenja za rad."}]},"4":{"hr":[{"v":1,"t":"Kad su Sanbalat, Tobija, Arapi, Amonci i Ašdođani čuli da napreduje popravljanje jeruzalemskih zidova - jer su se počele zatvarati pukotine - veoma se ražestiše."},{"v":2,"t":"Zakleše se svi zajedno da će napasti Jeruzalem i da će nas smesti."},{"v":3,"t":"Mi smo tada zazvali Boga našega i postavljali smo dnevnu i noćnu stražu da bismo zaštitili grad."},{"v":4,"t":"A Židovi govorahu: “Snage su nosačima klonule, a ruševina je mnogo: nećemo nikada stići sagraditi zida!”"},{"v":5,"t":"A naši neprijatelji rekoše: “Uvući ćemo se među njih prije nego što doznaju i opaze nas: tada ćemo ih poubijati i tako osujetiti pothvat!”"},{"v":6,"t":"A kad bi došli Židovi koji žive kraj njih, po deset bi nas puta upozoravali: “Idu protiv vas iz svih mjesta u kojima stanuju!”"},{"v":7,"t":"Postavili smo se u nizinama, iza zida i na goletima; rasporedio sam narod po rodovima, s mačevima, kopljima i lukovima."},{"v":8,"t":"Kad sam vidio kako se boje, ustao sam i objavio velikašima, odličnicima i ostalom narodu ovo: “Ne bojte se ovih ljudi! Mislite na Gospoda, velikoga i strašnoga, i borite se za svoju braću, za sinove i kćeri svoje, za žene i kuće svoje!”"},{"v":9,"t":"Kad su naši neprijatelji čuli da smo obaviješteni i da je Bog osujetio njihovu osnovu, mogli smo se vratiti k zidu, svaki svome poslu."},{"v":10,"t":"Ali je od toga dana samo polovica mojih momaka obavljala posao, a ostali su držali koplja, štitove, lukove i oklope, a glavari stajali iza doma Judina,"},{"v":11,"t":"koji je gradio zid. I nosači tereta držali su oružje: jednom je rukom svaki radio svoj posao, a u drugoj mu bilo oružje."},{"v":12,"t":"Svaki je od graditelja, dok je radio, nosio mač pripasan uz bok. Trubač je stajao kraj mene."},{"v":13,"t":"Rekao sam velikašima, odličnicima i ostalom narodu: “Posao je velik i zamašan, a mi se rasuli po zidu, daleko jedni od drugih:"},{"v":14,"t":"skupite se oko nas na mjesto gdje čujete glas trube, a Bog naš borit će se za nas.”"},{"v":15,"t":"Tako smo obavljali posao od rane zore do prvih zvijezda. Polovica je bila naoružana kopljima."},{"v":16,"t":"U to sam vrijeme još rekao narodu: “Svaki sa svojim slugom neka noći u Jeruzalemu: po redu ćemo noću stražariti, a danju raditi.”"},{"v":17,"t":"Ni ja, ni moja braća, ni moji momci, ni stražari koji su me pratili nismo skidali svojih haljina, svatko je držao pri ruci svoje oružje."}]},"5":{"hr":[{"v":1,"t":"Velika se vika digla među ljudima i ženama protiv njihove braće Židova."},{"v":2,"t":"Jedni su govorili: “Zalažemo svoje sinove i kćeri da bismo mogli nabaviti pšenice te jesti i živjeti.”"},{"v":3,"t":"Drugi su govorili: “Zalažemo svoja polja, vinograde svoje i kuće svoje da bismo mogli nabaviti pšenice za vrijeme gladi.”"},{"v":4,"t":"Drugi su opet govorili: “Moramo uzaimati novac na polja svoja i vinograde da bismo mogli isplatiti kraljeve namete."},{"v":5,"t":"Tijelo je naše kao tijelo braće naše, sinovi su naši kao i njihovi, a mi moramo predavati u ropstvo svoje sinove i kćeri; među našim kćerima neke su već robinje! A mi ne možemo ništa jer polja naša i vinograde drže drugi.”"},{"v":6,"t":"Razljutio sam se veoma kad sam čuo njihovu viku i te riječi."},{"v":7,"t":"Pošto sam u sebi promislio, prekorio sam velikaše i odličnike riječima: “Vi namećete teret svojoj braći!” I sazvao sam protiv njih velik zbor."},{"v":8,"t":"I rekao sam: “Mi smo, koliko smo mogli, otkupili svoju židovsku braću koja bijahu prodana poganima. A sada vi prodajete svoju braću da bismo ih otkupili!” Svi su šutjeli i nitko nije odgovorio."},{"v":9,"t":"Nastavio sam: “Nije dobro to što činite. Ne treba li da hodite u strahu Boga našega da se tako uklonimo ruglu neprijateljskih naroda?"},{"v":10,"t":"I ja, i moja braća, i moji momci davali smo im novaca i žita. Ali smo im dug oprostili."},{"v":11,"t":"Vratite im i vi još danas njihova polja, vinograde, maslinike i kuće njihove i oprostite im postotak u novcu, u žitu, u vinu, u ulju, što ste im ga nametnuli.”"},{"v":12,"t":"A oni odgovoriše: “Vratit ćemo; nećemo od njih ništa tražiti. Učinit ćemo kako si rekao.” Tada pozvah svećenike i naredih neka se zakunu da će učiniti kako su obećali."},{"v":13,"t":"Zatim istresoh skute svoje odjeće govoreći: “Neka Bog ovako istrese iz vlastite kuće i imanja svakog čovjeka koji se ne bude držao ovog obećanja! Tako bio istresen i ispražnjen!” A sav zbor odgovori “Amen!” hvaleći Jahvu. I narod je učinio prema ovom dogovoru."},{"v":14,"t":"I od dana kad mi je kralj naredio da budem upravitelj u zemlji Judinoj, od dvadesete do trideset i druge godine kraljevanja Artakserksa, za dvanaest godina ja i moja braća nismo nikada jeli upraviteljskog kruha."},{"v":15,"t":"Ali prijašnji upravitelji, moji prethodnici, ugnjetavahu narod: svakoga su dana od njega uzimali četrdeset šekela srebra za kruh; i njihove su sluge ugnjetavale narod. A ja nisam nikada tako činio, zbog straha Božjega."},{"v":16,"t":"Čak sam se jednako držao posla oko zida i nisam kupio ni jedne njive! Svi su moji momci bili ondje okupljeni na poslu."},{"v":17,"t":"Za mojim su stolom jeli Židovi i odličnici, njih stotinu i pedeset na broju, osim onih koji su k nama dolazili iz okolnih naroda."},{"v":18,"t":"Svakoga se dana o mom trošku pripremalo jedno goveče, šest biranih ovaca i peradi; svakih deset dana donosilo se obilje vina za sve. A opet nisam nikada tražio upraviteljskog poreza na kruh, jer je narod već bio teško opterećen."},{"v":19,"t":"Spomeni se, Bože moj, za moje dobro svega što sam učinio ovome narodu!"}]},"6":{"hr":[{"v":1,"t":"Kad su Sanbalat, Tobija, Gešem Arapin i ostali naši neprijatelji dočuli da sam obnovio zid i da nije u njemu ostalo pukotine - do toga vremena nisam zapravo bio namjestio krila na vratima -"},{"v":2,"t":"poručiše mi Sanbalat i Gešem: “Dođi da se sastanemo u Kefiri, u Dolini ononskoj.” Ali su mi oni zlo mislili."},{"v":3,"t":"Zato sam im poslao glasnike s ovim odgovorom: “Zauzet sam velikim poslom i ne mogu sići: posao bi zastao kad bih ga ostavio da dođem k vama!”"},{"v":4,"t":"Četiri su mi puta slali isti poziv i ja sam im odvraćao isti odgovor."},{"v":5,"t":"Tada, peti put, s istom nakanom, posla mi Sanbalat svoga slugu s otvorenim pismom."},{"v":6,"t":"U njemu je pisalo: “Čuje se u narodima - a Gašmu potvrđuje - da se ti i Židovi spremate na bunu; zato da i gradiš zid i da želiš postati njihovim kraljem, kako vele."},{"v":7,"t":"I da si postavio proroke da proglase tvoj uspjeh u Jeruzalemu i da kažu: Judeja ima kralja! Sada će ti glasovi stići kralju do ušiju: zato dođi da se posavjetujemo.”"},{"v":8,"t":"Ali sam mu ja odgovorio: “Ništa nije tako kao što tvrdiš; sve je to samo izmišljotina tvoga srca.”"},{"v":9,"t":"Jer su nas oni htjeli uplašiti govoreći: “Klonut će im ruke od posla i neće ga završiti nikada.” A ja sam, naprotiv, ukrijepio ruke svoje!"},{"v":10,"t":"Pošao sam Šemaji, sinu Delaje, sina Mehetabelova, koji se bijaše zatvorio u svojoj kući. On mi objavi: “Nađimo se u Domu Božjemu, usred Hekala, i zatvorimo vrata Hekala jer će doći da te ubiju. Jest, još noćas doći će da te ubiju!”"},{"v":11,"t":"A ja odgovorih: “Zar da bježi čovjek kao što sam ja? Koji čovjek, meni sličan, može ući u Hekal i ostati živ? Ne, ja ne idem.”"},{"v":12,"t":"I tada razabrah: nije ga poslao Bog, nego mi je objavio proroštvo, jer su ga Tobija i Sanbalat podmitili,"},{"v":13,"t":"da bih, uplašen, učinio onako te sagriješio. To bi im poslužilo da me ozloglase i da mi se rugaju!"},{"v":14,"t":"Sjeti se, Bože moj, Tobije i Sanbalata prema ovim njihovim djelima, a i proročice Noadje i ostalih proroka što me htjedoše uplašiti."},{"v":15,"t":"Zid je završen dvadeset i petog Elula, za pedeset i dva dana."},{"v":16,"t":"A kad su čuli svi naši neprijatelji i vidjeli svi pogani oko nas, bilo je to čudo u očima njihovim, jer su shvatili da je Bog naš učinio to djelo."},{"v":17,"t":"A onih dana mnogi su židovski velikaši često slali svoja pisma Tobiji i mnoga su primali od Tobije."},{"v":18,"t":"Jer u Judeji bijahu mnogi s njime zakletvom povezani: tÓa bio je u rodu sa Šekanijom, sinom Arahovim, i sinom njegovim Johananom, koji je uzeo za ženu kćer Mešulama, sina Berekjina."},{"v":19,"t":"I veličali su preda mnom njegova djela, a njemu prenosili moje riječi. Zato je Tobija i slao pisma da me uplaši."}]},"7":{"hr":[{"v":1,"t":"A kad je zid bio sagrađen i kad sam namjestio vratna krila, postavljeni su čuvari na vratima i pjevači i leviti."},{"v":2,"t":"Upravu sam Jeruzalema povjerio Hananiju, svome bratu, i Hananiji, zapovjedniku tvrđave, jer je ovaj bio čovjek povjerenja i bojao se Boga kao malo tko."},{"v":3,"t":"Rekao sam im: “Jeruzalemska vrata neka se ne otvaraju dok sunce ne ogrije; a dok ono bude još visoko, neka ih zatvore i prebace prijevornice. Treba postaviti straže uzete između žitelja jeruzalemskih: svakoga na njegovo mjesto, svakoga nasuprot njegovoj kući."},{"v":4,"t":"Grad je bio prostran i velik, ali je u njemu bilo malo stanovnika jer nije bilo sagrađenih kuća."},{"v":5,"t":"A Bog me moj nadahnuo te sam skupio velikaše, odličnike i narod da se unesu u rodovnike. Tada sam našao rodovnik onih koji su se prije vratili. U njemu nađoh zapisano:"},{"v":6,"t":"Evo ljudi iz pokrajine koji su došli iz sužanjstva u koje ih bijaše odveo Nabukodonozor, babilonski kralj. Vratili su se u Jeruzalem i Judeju, svaki u svoj grad."},{"v":7,"t":"Došli su sa Zerubabelom, Ješuom, Nehemijom, Azarjom, Raamjom, Nahamanijem, Mordokajem, Bilšanom, Misperetom, Bigvajem, Nehumom, Baanom. Broj ljudi naroda Izraelova:"},{"v":8,"t":"Paroševih sinova: dvije tisuće stotinu sedamdeset i dva;"},{"v":9,"t":"sinova Šefatjinih: tri stotine sedamdeset i dva;"},{"v":10,"t":"Arahovih sinova: šest stotina pedeset i dva!"},{"v":11,"t":"Pahat-Moabovih sinova, to jest Ješuinih i Joabovih sinova: dvije tisuće osam stotina i osamnaest;"},{"v":12,"t":"sinova Elamovih: tisuću dvjesta pedeset i četiri;"},{"v":13,"t":"Zatuovih sinova: osam stotina četrdeset i pet;"},{"v":14,"t":"sinova Zakajevih: sedam stotina i šezdeset;"},{"v":15,"t":"Binujevih sinova: šest stotina četrdeset i osam;"},{"v":16,"t":"sinova Bebajevih: šest stotina dvadeset i osam;"},{"v":17,"t":"Azgadovih sinova: dvije tisuće tri stotine dvadeset i dva;"},{"v":18,"t":"sinova Adonikamovih: šest stotina šezdeset i sedam;"},{"v":19,"t":"Bigvajevih sinova: dvije tisuće šezdeset i sedam;"},{"v":20,"t":"sinova Adinovih: šest stotina pedeset i pet;"},{"v":21,"t":"Aterovih sinova, to jest od Ezekije: devedeset i osam;"},{"v":22,"t":"sinova Hašumovih: trista dvadeset i osam;"},{"v":23,"t":"Besajevih sinova: trista dvadeset i četiri;"},{"v":24,"t":"sinova Harifovih: stotinu i dvanaest;"},{"v":25,"t":"Gibeonovih sinova: devedeset i pet;"},{"v":26,"t":"ljudi iz Betlehema i Netofe: stotinu osamdeset i osam;"},{"v":27,"t":"ljudi iz Anatota: stotinu dvadeset i osam;"},{"v":28,"t":"ljudi iz Bet Azmaveta: četrdeset i dva;"},{"v":29,"t":"ljudi iz Kirjat Jearima, Kefire i Beerota: sedam stotina četrdeset i tri;"},{"v":30,"t":"ljudi iz Rame i Gabe: šest stotina dvadeset i jedan;"},{"v":31,"t":"ljudi iz Mikmasa: stotinu dvadeset i dva;"},{"v":32,"t":"ljudi iz Betela i Aja: stotinu dvadeset i tri;"},{"v":33,"t":"ljudi iz Neba: pedeset i dva;"},{"v":34,"t":"sinova drugoga Elama: tisuću dvjesta pedeset i četiri;"},{"v":35,"t":"Harimovih sinova: trista dvadeset;"},{"v":36,"t":"ljudi iz Jerihona: trista četrdeset i pet;"},{"v":37,"t":"ljudi iz Loda, Hadida i Onona: sedam stotina dvadeset i jedan;"},{"v":38,"t":"sinova Senajinih: tri tisuće devet stotina i trideset."},{"v":39,"t":"Svećenika: sinova Jedajinih, to jest iz kuće Ješuine: devet stotina sedamdeset i tri;"},{"v":40,"t":"Imerovih sinova: tisuću pedeset i dva;"},{"v":41,"t":"sinova Fašhurovih: tisuću dvjesta četrdeset i sedam;"},{"v":42,"t":"Harimovih sinova: tisuću i sedamnaest."},{"v":43,"t":"Levita: Ješuinih sinova, to jest Kadmielovih i Hodvinih: sedamdeset i četiri."},{"v":44,"t":"Pjevača: Asafovih sinova: stotinu četrdeset i osam."},{"v":45,"t":"Vratara: sinova Šalumovih, sinova Aterovih, sinova Talmonovih, sinova Akubovih, Hatitinih sinova, sinova Šobajevih: stotinu trideset i osam."},{"v":46,"t":"Netinaca: sinova Sihinih, sinova Hasufinih, sinova Tabaotovih,"},{"v":47,"t":"sinova Kerosovih, sinova Sijajevih, sinova Fadonovih,"},{"v":48,"t":"sinova Lebaninih, sinova Hagabinih, sinova Šalmajevih,"},{"v":49,"t":"sinova Hananovih, sinova Gidelovih, sinova Gaharovih,"},{"v":50,"t":"sinova Reajinih, sinova Resinovih, sinova Nekodinih,"},{"v":51,"t":"sinova Gazamovih, sinova Uzinih, sinova Fasealovih,"},{"v":52,"t":"sinova Besajevih, sinova Merinimovih, sinova Nefišesimovih,"},{"v":53,"t":"sinova Bakbukovih, sinova Hakufinih, sinova Harhurovih,"},{"v":54,"t":"sinova Baslitovih, sinova Mehidinih, sinova Haršinih,"},{"v":55,"t":"sinova Barkošovih, sinova Sisrinih, sinova Tamahovih,"},{"v":56,"t":"sinova Nasijahovih, sinova Hatifinih."},{"v":57,"t":"Sinova Salomonovih slugu: sinova Sotajevih, sinova Soferetovih, sinova Feridinih,"},{"v":58,"t":"sinova Jaalinih, sinova Darkonovih, sinova Gidelovih,"},{"v":59,"t":"sinova Šefatjinih, sinova Hatilovih, sinova Pokeret-Sebajinih, sinova Amonovih."},{"v":60,"t":"Svega netinaca i sinova Salomonovih slugu tri stotine devedeset i dva."},{"v":61,"t":"Slijedeći ljudi koji su došli iz Tel Melaha, Tel Harše, Keruba, Adona i Imera nisu mogli dokazati da su njihove obitelji i njihov rod izraelskog podrijetla:"},{"v":62,"t":"sinovi Delajini, sinovi Tobijini, sinovi Nekodini: šest stotina četrdeset i dva."},{"v":63,"t":"A od svećenika: sinovi Hobajini, sinovi Hakosovi, sinovi Barzilaja - onoga koji se oženio jednom od kćeri Barzilaja Gileađanina te uzeo njegovo ime."},{"v":64,"t":"Ovi su ljudi tražili svoj zapis u rodovnicima, ali ga nisu mogli naći: bili su isključeni iz svećeništva"},{"v":65,"t":"i namjesnik im zabrani blagovati od svetinja sve dok se ne pojavi svećenik za Urim i Tumin."},{"v":66,"t":"Ukupno je na zboru bilo četrdeset i dvije tisuće tri stotine i šezdeset osoba,"},{"v":67,"t":"ne računajući njihove sluge i sluškinje, kojih bijaše sedam tisuća tri stotine trideset i sedam. Bilo je i dvije stotine četrdeset i pet pjevača i pjevačica,"},{"v":68,"t":"četiri stotine trideset i pet deva i šest tisuća sedam stotina i dvadeset magaraca."},{"v":69,"t":"Pojedini glavari obitelji dadoše priloge za gradnju. Namjesnik je položio u riznicu tisuću drahmi zlata, pedeset vrčeva, trideset svećeničkih haljina."},{"v":70,"t":"Neki su od glavara obitelji dali u poslovnu riznicu dvadeset tisuća drahmi zlata i dvije tisuće dvije stotine mina srebra."},{"v":71,"t":"A darova ostalog puka bilo je do dvadeset tisuća drahmi zlata, dvije tisuće mina srebra i šezdeset i sedam svećeničkih haljina."},{"v":72,"t":"Svećenici, leviti, vratari, pjevači, netinci i sav Izrael naseliše se svaki u svoj grad. A kada se približio sedmi mjesec, već su sinovi Izraelovi bili u svojim gradovima."}]},"8":{"hr":[{"v":1,"t":"Tada se skupi sav narod kao jedan čovjek na trg koji je pred Vodenim vratima. Rekoše književniku Ezri da donese knjigu Mojsijeva zakona što ga je Jahve dao Izraelu."},{"v":2,"t":"I prvoga dana sedmoga mjeseca svećenik Ezra donese Zakon pred zbor ljudi, žena i sviju koji su bili sposobni da ga razumiju."},{"v":3,"t":"Na trgu koji je pred Vodenim vratima počeo je čitati knjigu, od ranoga jutra do podneva, pred ljudima, ženama i pred onima koji su bili zreli. Sav je narod pozorno slušao knjigu Zakona."},{"v":4,"t":"Književnik Ezra stajaše na drvenu besjedištu koje su podigli za tu zgodu. Kraj njega stajahu: s desne strane Matitja, Šema, Anaja, Urija, Hilkija i Maaseja, a s lijeve strane Pedaja, Mišael, Malkija, Hašum, Hašbadana, Zaharija i Mešulam."},{"v":5,"t":"Ezra je otvorio knjigu naočigled svemu narodu - jer je bio poviše od svega naroda - a kad ju je otvorio, sav narod ustade."},{"v":6,"t":"Tada Ezra blagoslovi Jahvu, Boga velikoga, a sav narod, podignutih ruku, odgovori: “Amen! Amen!” Zatim su kleknuli i poklonili se pred Jahvom, licem do zemlje."},{"v":7,"t":"A leviti Ješua, Bani, Šerebja, Jamin, Akub, Šabtaj, Hodija, Maaseja, Kelita, Azarja, Jozabad, Hanan i Pelaja objašnjavahu Zakon narodu, a narod stajaše na svome mjestu."},{"v":8,"t":"I čitahu iz knjige Božjeg zakona po odlomcima i razlagahu smisao da narod može razumjeti što se čita."},{"v":9,"t":"Potom namjesnik Nehemija, i svećenik i književnik Ezra, i leviti koji poučavahu narod rekoše svemu narodu: “Ovo je dan posvećen Jahvi, Bogu vašemu! Ne tugujte, ne plačite!” Jer sav narod plakaše slušajući riječi Zakona."},{"v":10,"t":"I još im reče Nehemija: “Pođite i jedite masna jela, i pijte slatko, i pošaljite dio onima koji nemaju ništa pripremljeno, jer ovo je dan posvećen našem Gospodu. Ne žalostite se: radost Jahvina vaša je jakost.”"},{"v":11,"t":"I leviti umirivahu sav narod govoreći: “Umirite se: ovaj je dan svet. Ne tugujte!”"},{"v":12,"t":"I ode sav narod da jede i pije, i da šalje obroke, i da slavi veliko slavlje: jer su shvatili riječi koje su im objavljene."},{"v":13,"t":"Drugog dana skupiše se glavari obitelji svega naroda, svećenici i leviti oko književnika Ezre da prouče riječi Zakona."},{"v":14,"t":"I nađoše napisano u Zakonu što ga je Jahve naredio preko sluge Mojsija: “Sinovi Izraelovi neka borave pod sjenicama za svečanosti u sedmom mjesecu.”"},{"v":15,"t":"Čim su čuli, proglasiše u svim svojim gradovima i u Jeruzalemu: “Idite u goru i donesite granja maslinova i granja divlje masline, mirtovih i palmovih grana i granja ostaloga lisnatog drveća da načinimo sjenice, kako je propisano.”"},{"v":16,"t":"I ode narod i donese granja i načiniše sjenice, svaki na svom krovu i svojim dvorištima, u predvorjima Doma Božjega, na trgu kod Vodenih vrata i na onom kod Efrajimovih vrata."},{"v":17,"t":"Sav zbor onih koji su se vratili iz sužanjstva načini sjenice i boravili su u njima - Izraelci nisu toga činili od vremena Jošue, sina Nunova, sve do toga dana. I bila je veoma velika radost."},{"v":18,"t":"Ezra je čitao knjigu Zakona Božjeg svakog dana, od prvoga do posljednjega. Sedam se dana svetkovao blagdan, a osmoga je dana bio svečani zbor, kako je propisano."}]},"9":{"hr":[{"v":1,"t":"Dvadeset i četvrtoga dana toga mjeseca skupiše se Izraelci na post, u pokorničkim vrećama i posuti prašinom."},{"v":2,"t":"Rod se Izraelov odvojio od svih tuđinaca: pristupili su i ispovijedali svoje grijehe i bezakonja svojih otaca."},{"v":3,"t":"Stajali su, svatko na svome mjestu, i čitali knjigu Zakona Jahve, Boga svoga, četvrtinu dana; za druge su četvrtine ispovijedali svoje grijehe i klanjali se Jahvi, Bogu svome."},{"v":4,"t":"A Ješua, Bani, Kadmiel, Šebanija, Buni, Šerebja, Bani i Kenani, popevši se na poviše mjesto za levite, vapili su snažnim glasom Jahvi, Bogu svome."},{"v":5,"t":"I govorahu leviti Ješua, Kadmiel, Bani, Hašabneja, Šerebja, Hodija, Šebanija i Petahja: “Ustanite, blagoslivljajte Jahvu, Boga našega! Blagoslovljen da si, Jahve, Bože naš, odvijeka dovijeka! I neka je blagoslovljeno tvoje Ime slavno, iznad svakog blagoslova i hvale uzvišeno."},{"v":6,"t":"Ti si, Jahve, Jedini! Ti si stvorio nebo, i nebesa nad nebesima, i vojsku njihovu, zemlju i sve što je na njoj, mora i što je u njima. Ti sve to oživljavaš, i vojske se nebeske tebi klanjaju."},{"v":7,"t":"Ti si, Jahve, Bog, koji si Abrama izabrao, iz Ura kaldejskoga njega izveo i dao mu ime Abraham."},{"v":8,"t":"Vjerno si srce njegovo pred sobom našao i Savez s njim sklopio da ćeš mu dati zemlju kanaansku, i hetitsku i amorejsku, i perižansku, jebusejsku i girgašansku, njemu i potomstvu njegovu. I svoja si obećanja ispunio, jer si pravedan."},{"v":9,"t":"Nevolju si otaca naših u Egiptu vidio, i vapaj si njihov čuo kraj Mora crvenoga."},{"v":10,"t":"Znacima si se i čudesima oborio na faraona i na sve sluge njegove, i na sav narod zemlje njegove; jer znao si kolika je bila protiv njih drskost njihova. Sebi si ime stekao koje do danas traje."},{"v":11,"t":"More si pred njima razdvojio: prešli su usred mora po suhu. U dubine si utopio progonitelje njihove kao kamen među vode silovite."},{"v":12,"t":"Stupom oblaka danju si ih vodio, a noću si stupom ognjenim svijetlio im po putu kojim su hodili."},{"v":13,"t":"Na goru si Sinajsku sišao i s neba im govorio; i dao si im pravedne naredbe, čvrste zakone, zapovijedi izvrsne i uredbe."},{"v":14,"t":"Ti si im objavio svoju svetu subotu, zapovijedi, naredbe i Zakon si im propisao po glasu sluge svoga Mojsija."},{"v":15,"t":"S neba si ih hranio kruhom za njihove gladi, za njihovu si žeđ iz stijene vodu izveo. Ti si im zapovjedio da pođu zaposjesti zemlju za koju si se zakleo da ćeš im dati."},{"v":16,"t":"Ali se oni i oci naši uzjoguniše, vratove ukrutiše i zapovijedi tvojih nisu slušali."},{"v":17,"t":"Poslušnost su odbili, zaboravili čudesa što si ih za njih učinio; ukrutili su vratove, a u glavu uvrtjeli da u ropstvo se svoje vrate, u Egipat. Ali ti si Bog praštanja, milosrdan i blag, na gnjev si spor, a u milosrdđu velik: i nisi ih ostavio!"},{"v":18,"t":"Čak su načinili tele saliveno, 'To bog je tvoj', rekoše, 'koji te izveo iz Egipta!' I teško su hulili,"},{"v":19,"t":"a ti u beskrajnom milosrđu nisi ih napuštao u pustinji: stup se oblaka nije pred njima skrivao, danju ih je putem vodio, a stup je plameni noću pred njima svijetlio putem kojim su hodili."},{"v":20,"t":"Dao si im svoga Duha dobrog da ih naučiš mudrosti, mÓane svoje nisi uskratio njihovim ustima, i u žeđi si im vode pružio."},{"v":21,"t":"Četrdeset godina krijepio si ih u pustinji: ništa im nije nedostajalo: niti im se odijelo deralo, niti su im noge oticale."},{"v":22,"t":"I dao si im kraljevstva i narode i razdijelio ih granicama: zaposjeli su zemlju Sihona, kralja hešbonskoga, i zemlju Oga, kralja bašanskoga."},{"v":23,"t":"I sinove si im umnožio kao zvijezde nebeske, i u zemlju si ih doveo za koju si rekao njihovim ocima da će ući u nju i zaposjesti je."},{"v":24,"t":"Sinovi su ušli i pokorili zemlju, a ti si pred njima svladao stanovnike zemlje, Kanaance, i predao si u ruke njihove kraljeve i narode zemlje da rade s njima što ih je volja;"},{"v":25,"t":"osvojili su gradove tvrde i zemlju plodnu i naslijedili kuće pune svakog dobra, isklesane zdence, vinograde, maslinike i mnogo plodnog drveća: jeli su, sitili se i debljali i uživali u velikoj dobroti tvojoj."},{"v":26,"t":"Ali su se bunili i odvrgli tebe, i Zakon su tvoj bacili za leđa, ubijali su proroke, koji su ih obraćali da se tebi vrate, i grdno su hulili."},{"v":27,"t":"U ruke si ih tada predao osvajačima, koji su ih tlačili. A u vrijeme muke svoje tebi su vapili i ti si ih s neba uslišio i u velikoj dobroti svojoj slao si im izbavitelje, koji su ih iz ruku tlačitelja njihovih izbavljali."},{"v":28,"t":"Ali čim bi se smirili, opet su pred tobom zlo činili, a ti si ih puštao u ruke neprijatelja njihovih, koji su ih mučili. I opet su k tebi vapili i ti si ih s neba uslišio: u milosrđu svojem mnogo si ih puta izbavio."},{"v":29,"t":"Ti si ih opominjao da se vrate tvome Zakonu: ali se oni uzjoguniše, nepokorni tvojim zapovijedima; griješili su protiv naredaba tvojih, a čovjek živi kad ih obdržava. Leđa su izvlačili, šije ukrućivali i nisu slušali."},{"v":30,"t":"Mnogo si godina bio strpljiv s njima i svojim si ih Duhom opominjao po službi svojih proroka; no nisu slušali. Tada si ih predao u ruke naroda zemaljskih."},{"v":31,"t":"U velikom milosrđu svojem ti ih nisi uništio, ni ostavio ih nisi, jer si ti Bog milostiv i pun samilosti."},{"v":32,"t":"A sada, o Bože naš, veliki Bože, jaki i strašni, koji čuvaš Savez i dobrohotnost, neka ne bude pred licem tvojim neznatna sva ova nevolja koja je snašla nas, kraljeve naše i knezove, svećenike i proroke naše, očeve naše i sav narod tvoj od vremena asirskih kraljeva pa do danas."},{"v":33,"t":"Ti si pravedan u svemu što nas je snašlo, jer si ti pokazao vjernost, a mi zloću svoju."},{"v":34,"t":"Kraljevi naši i knezovi, svećenici i oci naši nisu vršili Zakona tvoga, nisu osluškivali naredaba tvojih i opomena koje si im davao."},{"v":35,"t":"Premda su bili u svom kraljevstvu, u velikim dobrima koja si im činio, u prostranoj i plodnoj zemlji koju si im dao, oni ti nisu služili i od svojih zlih djela nisu se odvraćali."},{"v":36,"t":"Mi smo danas, evo, robovi i u zemlji koju si bio dao ocima našim da uživaju njene plodove i njena dobra, evo u njoj mi robujemo."},{"v":37,"t":"Njeni obilni prihodi idu kraljevima koje si nam postavio zbog grijeha naših, i gospodare oni po volji svojoj tjelesima našim i stokom našom. Ah, u velikoj smo nevolji!"}]},"10":{"hr":[{"v":1,"t":"I zbog svega toga obvezujemo se pismeno na vjernost.” Na zapečaćenoj ispravi stajala su imena naših knezova, levita i svećenika ..."},{"v":2,"t":"Na zapečaćenoj ispravi su bili: namjesnik Nehemija, sin Hakalijin, i Sidkija,"},{"v":3,"t":"Seraja, Azarja, Jeremija,"},{"v":4,"t":"Pašhur, Amarja, Malkija,"},{"v":5,"t":"Hatuš, Šebanija, Maluk,"},{"v":6,"t":"Harim, Meremot, Obadja,"},{"v":7,"t":"Daniel, Gineton, Baruk,"},{"v":8,"t":"Mešulam, Abija, Mijamin,"},{"v":9,"t":"Maazja, Bilgaj, Šemaja - to su svećenici."},{"v":10,"t":"Zatim leviti: Ješua, sin Azanijin, Binuj, od sinova Henadadovih - Kadmiel,"},{"v":11,"t":"i braća njihova: Šekanija, Hodija, Kelita, Pelaja, Hanan,"},{"v":12,"t":"Mika, Rehob, Hašabja,"},{"v":13,"t":"Zakur, Šerebja, Šebanija,"},{"v":14,"t":"Hodija, Bani, Beninu."},{"v":15,"t":"Glavari naroda: Paroš, Pahat Moab, Elam, Zatu, Bani,"},{"v":16,"t":"Buni, Azgad, Bebaj,"},{"v":17,"t":"Adonija, Bigvaj, Adin,"},{"v":18,"t":"Ater, Ezekija, Azur,"},{"v":19,"t":"Hodija, Hašum, Besaj,"},{"v":20,"t":"Harif, Anatot, Nebaj,"},{"v":21,"t":"Magpijaš, Mešulam, Hazir,"},{"v":22,"t":"Mešezabel, Sadok, Jadua,"},{"v":23,"t":"Pelatja, Hanan, Anaja,"},{"v":24,"t":"Hošea, Hananija, Hašub,"},{"v":25,"t":"Haloheš, Pilha, Šobek,"},{"v":26,"t":"Rehum, Hašabna, Maaseja,"},{"v":27,"t":"Ahija, Hanan, Anan,"},{"v":28,"t":"Maluk, Harim, Baana."},{"v":29,"t":"... ali i ostali narod, svećenici, leviti - vratari, pjevači, netinci - i svi koji su se prema Zakonu Božjem odvojili od zemaljskih naroda, a i njihove žene, sinovi i kćeri, svi koji su bili sposobni da razumiju,"},{"v":30,"t":"priključili su se svojoj braći i glavarima te su se obvezali prisegom i zakletvom da će stupati prema Zakonu Božjem, koji je dan po rukama Mojsija, sluge Božjega, i da će držati i vršiti sve zapovijedi Jahve, Boga našega, njegove naredbe i zakone."},{"v":31,"t":"I osobito: da nećemo davati svojih kćeri narodima zemaljskim i njihovih kćeri nećemo uzimati svojim sinovima."},{"v":32,"t":"I ako narodi zemlje donesu na prodaju robu ili kakvo god žito u dan subotnji, mi ništa nećemo od njih kupovati u subotu ni u drugi posvećeni dan. Svake sedme godine ostavljat ćemo zemlju da počine i otpuštati dugove svake ruke."},{"v":33,"t":"Uzeli smo kao obavezu: da ćemo svake godine davati trećinu šekela za bogoslužje u Domu Boga svojega:"},{"v":34,"t":"za postavljeni kruh, za trajne prinosnice i za svagdanje paljenice, za žrtve subotnje, mladog mjeseca, blagdanske i za okajnice, da se pomiri Izrael; i za svaku službu u Domu Boga našega."},{"v":35,"t":"Mi svećenici, leviti i narod bacili smo ždrijeb za prinos drva koja treba da određenog dana svake godine prema svojim obiteljima donosimo u Dom Boga našega za vatru na žrtveniku Jahve, Boga našega, kako je zapisano u Zakonu;"},{"v":36,"t":"da ćemo svake godine donositi u Dom Jahvin prvine od plodova zemlje i prve plodove svakoga drveta"},{"v":37,"t":"i prvorođene sinove i prvine svoje stoke, kako je to pisano u Zakonu - prvine od krupne i sitne stoke neka se odnose u Dom Boga našega, jer su određene svećenicima koji služe u Domu Boga našega."},{"v":38,"t":"Povrh toga prvine svojih naćava, plodova svakog drveta, novoga vina i ulja nosit ćemo svećenicima u sobe Doma Boga našega; a desetinu od svoje zemlje levitima, jer leviti uzimaju desetinu u svim mjestima gdje radimo."},{"v":39,"t":"Svećenik, sin Aronov, neka prati levite kad skupljaju desetinu. Leviti neka donose desetinu desetine u Dom Boga našega, u sobe riznice,"},{"v":40,"t":"jer su onamo dužni, Izraelci i leviti donositi prinos od žita, vina i ulja. Ondje se nalaze posude svetišta, svećenici u službi, vratari i pjevači. Nećemo više zanemarivati Doma Boga svojega."}]},"11":{"hr":[{"v":1,"t":"Tada se nastaniše knezovi narodni u Jeruzalemu. Ostali je narod bacao ždrijeb da od svakih deset ljudi izađe jedan koji će stanovati u svetom gradu Jeruzalemu, dok će ostalih devet ostati u drugim gradovima."},{"v":2,"t":"I narod je blagoslovio sve ljude koji su dragovoljno htjeli živjeti u Jeruzalemu."},{"v":3,"t":"A evo glavara pokrajinskih koji su se nastanili u Jeruzalemu i po gradovima Judeje. Izrael, svećenici, leviti, netinci i sinovi Salomonovih slugu nastanili su se u svojim gradovima, svaki na svome posjedu."},{"v":4,"t":"U Jeruzalemu se nastaniše sinovi Judini i sinovi Benjaminovi. Od sinova Judinih: Ataja, sin Uzije, sina Zaharijina, sina Amarjina, sina Šefatjina, sina Mahalalelova, od sinova Faresovih;"},{"v":5,"t":"Maaseja, sin Baruha, sina Kol-Hozea, sina Hazaje, sina Adaje, sina Jojariba, sina Zaharije, sina Šelina."},{"v":6,"t":"Svega je bilo Faresovih sinova u Jeruzalemu četiri stotine šezdeset i osam ljudi sposobnih za boj."},{"v":7,"t":"Evo Benjaminovih sinova: Salu, sin Mešulama, sina Joedova, sina Pedajina, sina Kolajina, sina Maasejina, sina Itielova, sina Ješajina,"},{"v":8,"t":"i braća njegova: sposobnih za boj devet stotina dvadeset i osam."},{"v":9,"t":"Joel, sin Zikrijev, bio je njihov zapovjednik, i Juda, sin Hasenuin, drugi upravitelj grada."},{"v":10,"t":"Od svećenika: Jedaja, Jojarib, Jakin,"},{"v":11,"t":"Seraja, sin Hilkije, sina Mešulama, sina Sadoka, sina Merajota, sina Ahituba, predstojnik Doma Božjega, i"},{"v":12,"t":"njihova braća koja su vršila službu u Domu: osam stotina dvadeset i dvojica; i Adaja, sin Jerohama, sina Pelalije, sina Amsija, sina Zaharije, sina Pašhura, sina Malkijina,"},{"v":13,"t":"i njegova braća, glavari obitelji: dvjesta četrdeset i dvojica; i Amasaj, sin Azarela, sina Ahzaja, sina Mešilemota, sina Imerova,"},{"v":14,"t":"i njihove braće, sposobnih za boj: stotinu dvadeset i osam. Zapovjednik nad njima bio je Zabdiel, sin Hagedolimov."},{"v":15,"t":"Od levita: Šemaja, sin Hašuba, sina Azrikama, sina Hašabje, sina Bunijeva;"},{"v":16,"t":"i Šabtaj i Jozabad, od glavara levitskih, za nadzor vanjskih poslova Doma Božjega;"},{"v":17,"t":"i Matanija, sin Miheja, sina Zabdijeva, sina Asafova, koji je ravnao psalmima, počinjao zahvale i molitve; i Bakbukja, drugi među svojom braćom; i Abda, sin Šamue, sina Galala, sina Jedutunova."},{"v":18,"t":"Svega je levita bilo u Svetom gradu: dvjesta osamdeset i četiri."},{"v":19,"t":"A vratari: Akub, Talmon i njihova braća koja su čuvala stražu na vratima: stotinu sedamdeset i dva."},{"v":20,"t":"A ostali Izraelci, svećenici i leviti, nastaniše se u svim gradovima Judeje, svaki na svojoj baštini i po naseljima u njihovim poljima."},{"v":21,"t":"Netinci su stanovali u Ofelu; Siha i Gišpa bijahu na čelu netinaca."},{"v":22,"t":"Predstojnik je levitima u Jeruzalemu bio Uzi, sin Banija, sina Hašabje, sina Matanije, sina Mihejina. On je bio od sinova Asafovih, koji su bili pjevači za službu Doma Božjega."},{"v":23,"t":"Jer je za njih bila kraljeva zapovijed i uredba za svakodnevnu službu."},{"v":24,"t":"Petahja, sin Mešezabelov, od sinova Zeraha, sina Judina, bio je kraljev povjerenik za sve poslove s narodom."},{"v":25,"t":"Od sinova Judinih nastanili su se u Kirjat Haarbi i njezinim zaseocima, u Dibonu i njegovim zaseocima, u Jekabseelu i njegovim naseljima,"},{"v":26,"t":"u Jesui, u Moladi, u Bet Peletu,"},{"v":27,"t":"u Hasar Šualu, u Beer Šebi i u njenim zaseocima,"},{"v":28,"t":"u Siklagu, u Mekoni i njenim zaseocima,"},{"v":29,"t":"u En Rimonu, u Sori, u Jarmutu,"},{"v":30,"t":"Zanoahu, Adulamu i njihovim naseljima; u Lakišu i njegovim poljima, u Azeki i njenim zaseocima: tako su se naselili od Beer Šebe sve do Hinomske doline."},{"v":31,"t":"Benjaminovi sinovi življahu u Gebi, Mikmasu, Aju i Betelu i u njihovim zaseocima,"},{"v":32,"t":"u Anatotu, Nobu, Ananiji,"},{"v":33,"t":"Hasoru, Rami, Gitajimu,"},{"v":34,"t":"Hadidu, Seboimu, u Nebalatu,"},{"v":35,"t":"Lodu, Ononu i u Dolini rukotvoraca."},{"v":36,"t":"Skupine levita nalazile su se u Judi i Benjaminu."}]},"12":{"hr":[{"v":1,"t":"Ovo su svećenici i leviti koji su došli sa Zerubabelom, sinom Šealtielovim, i Ješuom: Seraja, Jeremija, Ezra,"},{"v":2,"t":"Amarja, Maluk, Hatuš,"},{"v":3,"t":"Šekanija, Rehum, Meremot,"},{"v":4,"t":"Ido, Gineton, Abija,"},{"v":5,"t":"Mijamin, Maadja, Bilga,"},{"v":6,"t":"Šemaja, Jojarib, Jedaja,"},{"v":7,"t":"Salu, Amok, Hilkija i Jedaja. To su bili glavari svećenički i njihova braća za Ješuina vremena."},{"v":8,"t":"A leviti: Ješua, Binuj, Kadmiel, Šerebja, Juda i Matanija - ovaj potonji i njegova braća ravnali su hvalospjevima."},{"v":9,"t":"Bakbukja i Uni i braća njihova izmjenjivali su se s njima u službi."},{"v":10,"t":"Ješua rodi Jojakima; Jojakim rodi Elijašiba, a Elijašib Jojadu;"},{"v":11,"t":"Jojada rodi Jonatana, a Jonatan rodi Jaduu."},{"v":12,"t":"U Jojakimovo vrijeme glavari svećeničkih obitelji bijahu: Serajine obitelji Meraja; Jeremijine Hananja;"},{"v":13,"t":"Ezrine Mešulam; Amarjine Johanan;"},{"v":14,"t":"Malukove Jonatan; Šebanijine Josip;"},{"v":15,"t":"Harimove Adna; Meremotove Helkaj;"},{"v":16,"t":"Idove Zaharija; Ginetonove Mešulam;"},{"v":17,"t":"Abijine Zikri; Minjaminove ...; obitelji Moadjine Piltaj;"},{"v":18,"t":"Bilgine Šamua; Šemajine Jonatan;"},{"v":19,"t":"Jojaribove Matenaj; Jedajine Uzi;"},{"v":20,"t":"Saluove Kelaj; Amokove Eber;"},{"v":21,"t":"Hilkijine Hašabja; Jedajine Netanel."},{"v":22,"t":"U vrijeme Elijašiba, Jojade, Johanana i Jadue bili su popisani glavari levitskih obitelji i svećenici sve do kraljevanja Darija Perzijanca."},{"v":23,"t":"Sinovi Levijevi: glavari obitelji bili su zabilježeni u Knjizi ljetopisa, do vremena Johanana, sina Elijašibova."},{"v":24,"t":"Glavari levitski bili su: Hašabja, Šerebja, Ješua, Binuj, Kadmiel, a njihova braća, koja su stajala prema njima da pjevaju naizmjenično pohvale i zahvalnice prema uredbama Davida, Božjeg čovjeka,"},{"v":25,"t":"bijahu: Matanija, Bakbukja i Obadja. A Mešulam, Talmon i Akub, vratari, čuvali su stražu kod skladišta blizu vrata."},{"v":26,"t":"Ti su živjeli u vrijeme Jojakima, sina Ješue, sina Josadakova, i u vrijeme upravitelja Nehemije i književnika svećenika Ezre."},{"v":27,"t":"Kad je bila posveta jeruzalemskoga zida, potražili su levite svugdje gdje su stanovali da ih dovedu u Jeruzalem te proslave posvetu radošću, zahvalnicama i pjesmom uz cimbale, harfe i citre."},{"v":28,"t":"I skupiše se pjevači, sinovi Levijevi, iz kraja oko Jeruzalema, iz netofatskih sela,"},{"v":29,"t":"iz Bet Hagilgala, iz Gebe i polja Azmaveta: jer su pjevači sebi sagradili sela oko Jeruzalema."},{"v":30,"t":"Svećenici i leviti očistili su sebe, a zatim su očistili narod, vrata i zid."},{"v":31,"t":"Tada sam izveo judejske knezove na zid i sastavio dva velika zbora. Prvi je išao desno niza zid, prema Smetlišnim vratima;"},{"v":32,"t":"za njima su išli Hošaja i polovina judejskih knezova -"},{"v":33,"t":"Azarja, Ezra i Mešulam,"},{"v":34,"t":"Juda, Benjamin, Šemaja i Jeremija,"},{"v":35,"t":"a od svećeničkih sinova s trubljama: Zaharija, sin Jonatana, sina Šemaje, sina Matanije, sina Mikaje, sina Zakura, sina Asafa,"},{"v":36,"t":"s braćom njihovom Šemajom, Azarelom, Milalajem, Gilalajem, Maajem, Netanelom, Judom, Hananijem, s glazbalima Davida, Božjega čovjeka. A Ezra, književnik, išao je pred njima."},{"v":37,"t":"Kod Izvorskih vrata popeli su se njima nasuprot kraj stepenica Davidova grada, zidnim usponom od Davidove palače sve do Vodenih vrata na istoku."},{"v":38,"t":"Drugi zbor, a za njim ja i polovica narodnih knezova, išao je nalijevo zidom i Pećkom kulom sve do Tržnog zida,"},{"v":39,"t":"pa onda iznad Efrajimovih vrata, Starih vrata, Ribljih vrata, Hananelove kule, kule Meaha, sve do Ovčjih vrata. Zaustavili su se kod Zatvorskih vrata."},{"v":40,"t":"Potom su oba zbora zauzela mjesto u Domu Božjem. Tako i ja i sa mnom polovica odličnika,"},{"v":41,"t":"svećenici Elijakim, Maaseja, Minjamin, Mikaja, Elijoenaj, Zaharija, Hananija s trubama,"},{"v":42,"t":"zatim Maaseja, Šemaja, Eleazar, Uzi, Johanan, Malkija, Elam i Ezer. Pjevači su pjevali pod ravnanjem Jizrahjinim."},{"v":43,"t":"Toga su dana prinesene velike žrtve, ljudi su dali oduška radosti, jer ih je Bog ispunio velikom radošću, veselile se i žene i djeca. I radost Jeruzalema čula se nadaleko."},{"v":44,"t":"U to su vrijeme postavljeni ljudi da nadziru spremišta prinosa, prvina, desetina i da s polja uz gradove sabiru dijelove koje Zakon dodjeljuje svećenicima i levitima. Jer su se Judejci radovali svećenicima i levitima koji su bili u službi."},{"v":45,"t":"Oni su vršili službu Bogu svome i službu očišćenja - kao i pjevači i vratari - prema odredbi Davida i njegova sina Salomona."},{"v":46,"t":"Jer od Davidovih i Asafovih dana, od davnine, postoje pjevački glavari i pjesme pohvalne i zahvalnice Bogu."},{"v":47,"t":"Zato je sav Izrael u vrijeme Zerubabela i u Nehemijino vrijeme dan za danom davao dijelove određene za pjevače i vratare. Davali su levitima posvećene darove, a leviti su davali sinovima Aronovim."}]},"13":{"hr":[{"v":1,"t":"U ono vrijeme čitala se narodu knjiga Mojsijeva i ondje se našlo zapisano da Amonac i Moabac ne smiju nikada ući u zbor Božji,"},{"v":2,"t":"jer nisu sinovima Izraelovima izašli u susret s kruhom i vodom, nego su čak najmili protiv njih Bileama da ih prokune, ali je naš Bog obratio kletvu u blagoslov."},{"v":3,"t":"Kad su čuli Zakon, isključili su iz Izraela sve strance."},{"v":4,"t":"A prije toga svećenik Elijašib, postavljen nad sobama Doma Boga našega, bijaše svom rođaku Tobiji"},{"v":5,"t":"uredio prostranu sobu gdje su se prije ostavljali prinosi, tamjan, posuđe, desetine žita, vina i ulja, određene za levite, pjevače i vratare, i doprinosi za svećenike."},{"v":6,"t":"U to vrijeme nisam bio u Jeruzalemu, jer sam trideset i druge godine babilonskog kralja Artakserksa otišao kralju; ali poslije nekog vremena izmolio sam u kralja"},{"v":7,"t":"da se mogu vratiti u Jeruzalem. Tada doznadoh za zlo djelo što ga učini Elijašib uredivši Tobiji sobu u predvorjima Doma Božjega."},{"v":8,"t":"To me veoma rasrdilo: izbacih iz sobe sav namještaj Tobijina stana"},{"v":9,"t":"i naredih da se sobe očiste, zatim unesoh onamo posuđe Doma Božjega, prinose i tamjan."},{"v":10,"t":"Doznadoh i to da levitima nisu davali njihovih dijelova i da su se i leviti i pjevači, određeni za službu, razbježali svaki u svoje polje."},{"v":11,"t":"I prekorih odličnike i rekoh: “Zašto je zapušten Dom Božji?” Zatim skupih levite i pjevače i vratih ih k njihovim službama."},{"v":12,"t":"Tada je sva Judeja donosila u spremišta desetinu žita, vina i ulja."},{"v":13,"t":"Nad spremištima postavio sam svećenika Šelemju, književnika Sadoka i levita Pedaju, a uz njih Hanana, sina Zakura, sina Matanijina. Njih su smatrali pouzdanima; njihova je dužnost bila da dijele svojoj braći."},{"v":14,"t":"Zato, sjeti se mene, Bože moj: ne prezri mojih pobožnih djela koja učinih za Dom Boga svoga i za službu u njemu."},{"v":15,"t":"U ono sam vrijeme vidio u Judeji ljude koji gaze u tijescima u dan subotnji; drugi su nosili snopove žita, tovarili na magarce vino, grožđe, smokve i svakojake terete da ih u dan subotnji unesu u Jeruzalem. I prekorih ljude što u taj dan prodaju živež."},{"v":16,"t":"A Tirci koji su živjeli u Jeruzalemu donosili su onamo ribu i svakovrsnu robu da je prodaju Židovima u subotu."},{"v":17,"t":"Prekorih judejske velikaše i rekoh im: “Kakvo to zlo djelo činite i skrnavite dan subotnji?"},{"v":18,"t":"Nisu li tako činili i vaši oci te je Bog naš doveo svu ovu nesreću na nas i na ovaj grad? A zar vi želite umnažati gnjev protiv Izraela skrnaveći subotu?”"},{"v":19,"t":"I zapovjedih još da uoči subote, kad se mrak spusti na jeruzalemska vrata, zatvore njihova krila i rekoh neka se ne otvaraju do iza subote! Postavio sam nekoliko svojih momaka na vrata da se ne unosi nikakav tovar u dan subotnji."},{"v":20,"t":"Jednom su ili dvaput trgovci i prodavači svakovrsne robe proveli noć izvan Jeruzalema,"},{"v":21,"t":"ali sam ih upozorio i rekao im: “Zašto provodite noć pod zidom? Ako to ponovite, dignut ću na vas ruku!” Od toga vremena nisu više dolazili u subotu."},{"v":22,"t":"Zapovjedio sam levitima da se očiste i da dođu čuvati vrata, kako bi se svetkovao dan subotnji. I za ovo se spomeni mene, Bože moj, i smiluj mi se po svome velikom milosrđu!"},{"v":23,"t":"Onih sam dana vidio i Židove koji se bijahu oženili Ašdođankama, Amonkama i Moapkama."},{"v":24,"t":"Polovica njihovih sinova govorila je ašdodski ili jezikom ovoga ili onoga naroda: više nisu znali govoriti židovski."},{"v":25,"t":"Korio sam ih i proklinjao, neke sam i tukao, čupao im kose i zaklinjao ih Bogom: “Ne dajite svojih kćeri njihovim sinovima i ne uzimajte žene od njihovih kćeri za svoje sinove, a ni za sebe!"},{"v":26,"t":"Nije li u tome sagriješio Salomon, kralj Izraelov? Među mnogim narodima nije bilo kralja njemu ravna. Bio je drag Bogu svome i Gospod ga je postavio kraljem nad svim Izraelom. Ali su i njega tuđinke navele na grijeh!"},{"v":27,"t":"Treba li slušati kako i vi činite veliko zlo i postajete nevjerni Bogu našemu ženeći se tuđinkama?”"},{"v":28,"t":"Jedan od sinova Jojade, sina velikog svećenika Elijašiba, bijaše zet Horonjaninu Sanbalatu. Njega sam otjerao od sebe."},{"v":29,"t":"Spomeni se, Bože moj, ovih ljudi, jer su oskvrnuli svećeništvo i zavjet svećenički i levitski."},{"v":30,"t":"Tako sam ih očistio od svega tuđega i opet uspostavio službe svećenika i levita dodijelivši svakome njegov posao."},{"v":31,"t":"Uredio sam i da se nose drva u određene dane i prvine. Sjeti me se, Bože moj, za moje dobro!"}]}},"EST":{},"JOB":{"1":{"hr":[{"v":1,"t":"Bijaše nekoć u zemlji Usu čovjek po imenu Job. Bio je to čovjek neporočan i pravedan: bojao se Boga i klonio zla."},{"v":2,"t":"Rodilo mu se sedam sinova i tri kćeri."},{"v":3,"t":"Imao je sedam tisuća ovaca, tri tisuće deva, pet stotina jarmova goveda, pet stotina magarica i veoma mnogo služinčadi. Čovjek taj bijaše najugledniji među svim istočnjacima."},{"v":4,"t":"Sinovi su njegovi običavali naizmjence priređivati gozbe kod jednoga od njih, svaki u svoj dan, te su pozivali svoje tri sestre da jedu i piju s njima."},{"v":5,"t":"A kad bi se izredali s gozbama, Job bi ih pozvao na očišćenje. Uranio bi izjutra i prinio paljenice za svakog od njih; mislio je: “Tko zna nisu li mi sinovi griješili i u srcu Boga hulili!” Tako je Job svagda činio."},{"v":6,"t":"Jednoga dana dođu sinovi Božji da stanu pred Jahvu, a među njima pristupi i Satan."},{"v":7,"t":"Jahve tad upita Satana: “Odakle dolaziš?” - “Evo prođoh zemljom i obiđoh je”, odgovori on."},{"v":8,"t":"Nato će Jahve: “Nisi li zapazio slugu moga Joba? Njemu na zemlji nema ravna. Čovjek je to neporočan i pravedan, boji se Boga i kloni zla!”"},{"v":9,"t":"A Satan odgovori Jahvi: “Zar se Job uzalud Boga boji?"},{"v":10,"t":"Zar nisi ogradio njega, kuću mu i sav posjed njegov? Blagoslovio si djelo njegovih ruku, stoka mu se namnožila po zemlji."},{"v":11,"t":"Ali pruži jednom ruku i dirni mu u dobra: u lice će te prokleti!”"},{"v":12,"t":"“Neka ti bude! - reče Jahve Satanu. - Sa svime što ima radi što ti drago; samo ruku svoju na nj ne diži.” I Satan ode ispred lica Jahvina."},{"v":13,"t":"Jednoga dana, dok su Jobovi sinovi i kćeri jeli i pili vino u kući najstarijeg brata,"},{"v":14,"t":"dođe glasnik k Jobu i reče: “Tvoji su volovi orali a magarice pokraj njih pasle,"},{"v":15,"t":"kad iznenada Sabejci navališe na njih i oteše ih, pobivši momke oštrim mačem. Jedini ja utekoh da ti ovo javim.”"},{"v":16,"t":"Dok je on još to govorio, dođe drugi i reče: “Oganj Božji udari s neba, spali tvoje ovce i pastire te ih proždrije. Jedini ja utekoh da ti javim.”"},{"v":17,"t":"Dok je još govorio, dođe treći i reče: “Kaldejci navališe sa tri čete na tvoje deve i oteše ih, pobivši momke oštrim mačem. Jedini ja utekoh da ti javim.”"},{"v":18,"t":"Dok je ovaj još govorio, dođe četvrti i reče: “Tvoji su sinovi i kćeri jeli i pili vino u kući najstarijeg brata."},{"v":19,"t":"I gle, vjetar se silan diže iz pustinje, udari na sva četiri ugla kuće, obori je na djecu te ona zaglaviše. Jedini ja utekoh da ti javim.”"},{"v":20,"t":"Tad ustade Job, razdrije haljinu na sebi, obrija glavu pa ničice pade na zemlju, pokloni se"},{"v":21,"t":"i reče: “Go iziđoh iz krila majčina, go ću se onamo i vratiti. Jahve dao, Jahve oduzeo! Blagoslovljeno ime Jahvino!”"},{"v":22,"t":"Uza sve to, nije sagriješio Job niti je kakvu ludost protiv Boga izustio."}]},"2":{"hr":[{"v":1,"t":"Jednoga dana dođu opet sinovi Božji da stanu pred Jahvu, a među njima pristupi i Satan."},{"v":2,"t":"Jahve tad upita Satana: “Odakle dolaziš?” - “Evo prođoh zemljom i obiđoh je”, odgovori on."},{"v":3,"t":"Nato će Jahve: “Nisi li zapazio slugu moga Joba? Njemu na zemlji nema ravna. Čovjek je to neporočan i pravedan: boji se Boga i kloni zla! On je još postojan u neporočnosti, pa si me uzalud izazvao da ga upropastim.”"},{"v":4,"t":"A Satan odvrati: “Koža za kožu! Sve što čovjek ima dat će za život."},{"v":5,"t":"Ali pruži ruku, dotakni se kosti njegove i mesa: u lice će te prokleti!”"},{"v":6,"t":"“Neka ti bude! - reče Jahve Satanu. - U tvojoj je ruci; život mu samo sačuvaj!”"},{"v":7,"t":"I Satan ode ispred lica Jahvina. On udari Joba zlim prištem od tabana do tjemena."},{"v":8,"t":"Job uze crijep da se struže njime i sjede u pepeo."},{"v":9,"t":"Tada mu njegova žena reče: “Zar si još postojan u neporočnosti? Prokuni Boga i umri!”"},{"v":10,"t":"Job joj odgovori: “Brbljaš kao luđakinja! Kad od Boga primamo dobro, zar da onda i zlo ne primimo?” U svemu tome Job nije sagriješio svojim usnama."},{"v":11,"t":"U to čuše tri Jobova prijatelja za sve nevolje koje ga zadesiše; svaki se zaputi iz svoga kraja - Elifaz iz Temana, Bildad iz Šuaha, Sofar iz Naama - i odlučiše da odu zajedno ožaliti ga i utješiti."},{"v":12,"t":"A kad su izdaleka upravili oči na njega, nisu ga prepoznali. Tad udariše u plač; svaki razdrije svoju haljinu i prosu prah po glavi."},{"v":13,"t":"Potom sjedoše kraj njega na zemlju i ostadoše tako sedam dana i sedam noći. Nijedan mu ne progovori ni riječi, jer vidješe da je velika njegova bol."}]},"3":{"hr":[{"v":1,"t":"Napokon otvori Job usta i prokle dan svoj;"},{"v":2,"t":"poče svoju besjedu i reče:"},{"v":3,"t":"“O, ne bilo dana kad sam se rodio i noći što javi: 'Začeo se dječak!'"},{"v":4,"t":"U crnu tminu dan taj nek se prometne! S visina se njega Bog ne spominjao, svjetlost sunčeva ne svijetlila mu više!"},{"v":5,"t":"Mrak i sjena smrtna o nj se otimali, posvema ga tmina gusta prekrila, pomrčine dnevne stravom ga morile!"},{"v":6,"t":"O, da bi ga tama svega presvojila, nek' se ne dodaje danima godine, nek' ne ulazi u brojenje mjeseci!"},{"v":7,"t":"A noć ona bila žalosna dovijeka, ne čulo se u njoj radosno klicanje!"},{"v":8,"t":"Prokleli je oni štono dan proklinju i Levijatana probudit' su kadri!"},{"v":9,"t":"Pomrčale zvijezde njezina svanuća, zaludu se ona vidjelu nadala, i zorinih vjeđa ne gledala nigda!"},{"v":10,"t":"Što mi od utrobe ne zatvori vrata da sakrije muku od mojih očiju!"},{"v":11,"t":"Što nisam mrtav od krila materina, što ne izdahnuh izlazeć' iz utrobe?"},{"v":12,"t":"Čemu su me dva koljena prihvatila i dojke dvije da me nejaka podoje?"},{"v":13,"t":"U miru bih vječnom počivao sada, spavao bih, pokoj svoj bih uživao"},{"v":14,"t":"s kraljevima i savjetnicima zemlje koji su sebi pogradili grobnice,"},{"v":15,"t":"ili s knezovima, zlatom bogatima, što su kuće svoje srebrom napunili."},{"v":16,"t":"Ne bih bio - k'o nedonošče zakopano, k'o novorođenče što svjetla ne vidje."},{"v":17,"t":"Zlikovci se više ne obijeste ondje, iznemogli tamo nalaze počinka."},{"v":18,"t":"Sužnjeve na miru tamo ostavljaju: ne slušaju više poviku stražara."},{"v":19,"t":"Malen ondje leži zajedno s velikim, rob je slobodan od gospodara svoga."},{"v":20,"t":"Čemu darovati svjetlo nesretniku i život ljudima zagorčene duše"},{"v":21,"t":"koji smrt ištu, a ona ne dolazi, i kao za blagom za njome kopaju?"},{"v":22,"t":"Grobnom bi se humku oni radovali, klicali od sreće kad bi grob svoj našli."},{"v":23,"t":"Što će to čovjeku kom je put sakriven, koga je Bog sa svih strana zapriječio?"},{"v":24,"t":"Zato videć' hranu, uzdahnuti moram, k'o voda se moji razlijevaju krici."},{"v":25,"t":"Obistinjuje se moje strahovanje, snalazi me, evo, čega god se bojah."},{"v":26,"t":"Pokoja ni mira meni više nema, u mukama mojim nikad mi počinka.”"}]},"4":{"hr":[{"v":1,"t":"Tad prozbori Elifaz Temanac i reče:"},{"v":2,"t":"“Možeš li podnijeti da ti progovorim? Ali tko se može uzdržat' od riječi!"},{"v":3,"t":"Eto, mnoge ljude ti si poučio, okrijepio si iznemogle mišice;"},{"v":4,"t":"riječju svojom klonule si pridizao, ojačavao si koljena klecava."},{"v":5,"t":"A kad tebe stiže, klonuo si duhom, na tebe kad pade, čitav si se smeo!"},{"v":6,"t":"Zar pobožnost tvoja nadu ti ne daje, neporočnost tvoja životu ufanje?"},{"v":7,"t":"TÓa sjeti se: nevin - propade li kada? Kada su zatrti bili pravednici?"},{"v":8,"t":"Iz iskustva zborim: nesrećom tko ore i nevolju sije, nju će i požeti."},{"v":9,"t":"Od daha Božjega oni pogibaju, na gnjevni mu disaj nestaju sa zemlje."},{"v":10,"t":"Rika lavlja, urlik leopardov krše se k'o zubi u lavića."},{"v":11,"t":"Lav ugiba jer mu nesta plijena, rasuli se mladi lavičini."},{"v":12,"t":"Tajna riječ se meni objavila, šapat njen je uho moje čulo."},{"v":13,"t":"Noću, kada snovi duh obuzmu i san dubok kad na ljude pada,"},{"v":14,"t":"strah i trepet mene su svladali, kosti moje žestoko se stresle."},{"v":15,"t":"Dah mi neki preko lica prođe, digoše se dlake na mom tijelu."},{"v":16,"t":"Stajao je netko - lica mu ne poznah - ali likom bješe pred očima mojim. Posvuda tišina; uto začuh šapat:"},{"v":17,"t":"'Zar je smrtnik koji pred Bogom pravedan? Zar je čovjek čist pred svojim Stvoriteljem?"},{"v":18,"t":"Ni slugama svojim više ne vjeruje, i anđele svoje za grijeh okrivljuje -"},{"v":19,"t":"kako ne bi onda goste stanova glinenih kojima je temelj u prahu zemaljskom. Gle, kao moljce njih sveudilj satiru:"},{"v":20,"t":"od jutra do mraka u prah pretvore, nestaju zasvagda - nitko i ne vidi."},{"v":21,"t":"Iščupan je kolčić njihova šatora, pogibaju skoro, mudrost ne spoznavši.'"}]},"5":{"hr":[{"v":1,"t":"Ded zazivlji! Zar će ti se tko odazvat'? Kojem li se svecu misliš sad obratit'?"},{"v":2,"t":"Doista, budalu njegov bijes ubija, luđaka će sasvim skončat ljubomora."},{"v":3,"t":"Bezumnika vidjeh kako korijen pušta, al' prokletstvo skoro na kuću mu pade."},{"v":4,"t":"Njegovi su sinci daleko od spasa, njih nezaštićene na Vratima tlače."},{"v":5,"t":"Ljetinu njihovu pojedoše gladni, sam Bog ju je njima oteo iz usta, a žedni hlepe za njihovim dobrima."},{"v":6,"t":"Ne, opačina ne izbija iz zemlje, nit' nevolja iz tla može nići sama,"},{"v":7,"t":"nego čovjek rađa muku i nevolju kao što let orlov teži u visinu."},{"v":8,"t":"Al' ja bih se ipak Bogu utekao i pred njime stvar bih svoju razložio."},{"v":9,"t":"Nedokučiva on djela silna stvori, čudesa koja se izbrojit' ne mogu."},{"v":10,"t":"On kišom rosi po svem licu zemljinu i vodu šalje da nam polja natapa."},{"v":11,"t":"Da bi ponižene visoko digao, da bi ojađene srećom obdario,"},{"v":12,"t":"redom ruši ono što lukavci smisle, što god započeli, on im izjalovi."},{"v":13,"t":"On hvata mudre u njihovu lukavstvu, naume spletkara obraća u ništa."},{"v":14,"t":"Posred bijela dana zapadnu u tamu, pipaju u podne kao usred noći."},{"v":15,"t":"On iz njinih ralja izbavlja jadnika, iz silničkih ruku diže siromaha."},{"v":16,"t":"Tako se pokaže nada nevoljniku, i nepravda mora zatvoriti usta."},{"v":17,"t":"Da, blago čovjeku koga Bog odbaci! Stoga ti ne prezri karanje Svesilnog!"},{"v":18,"t":"On ranjava, ali i ranu povija, udara i svojom zacjeljuje rukom."},{"v":19,"t":"Iz šest će nevolja tebe izbaviti, ni u sedmoj zlo te dotaknuti neće."},{"v":20,"t":"U gladi, od smrti on će te spasiti, a u ratu, oštru će te otet maču."},{"v":21,"t":"Biču zla jezika uklonit će tebe, ispred otimača bez straha ćeš biti."},{"v":22,"t":"Suši i studeni ti ćeš se smijati i od divljih zvijeri strahovati nećeš."},{"v":23,"t":"Sklopit' ti ćeš savez s kamenjem na njivi, zvjerad divlja s tobom u miru će biti."},{"v":24,"t":"U šatoru svome mir ćeš uživati, dom svoj kad pohodiš netaknut će stajat."},{"v":25,"t":"Koljeno ćeš svoje gledat' gdje se množi i potomstvo gdje ti kao trava raste."},{"v":26,"t":"U grob ti ćeš leći kada budeš zreo, kao što se žito snosi kad dozori."},{"v":27,"t":"Sve motrismo ovo: istina je živa! zato sve za dobro svoje ti poslušaj.”"}]},"6":{"hr":[{"v":1,"t":"A Job progovori i reče:"},{"v":2,"t":"“O, kad bi se jad moj izmjeriti mog'o, a nevolje moje stavit' na tezulju!"},{"v":3,"t":"Teže one jesu od sveg pijeska morskog, i stoga mi riječi zastraniti znaju."},{"v":4,"t":"Strijele Svesilnoga u mojem su mesu, ljuti otrov njihov ispija mi dušu, Božje se strahote oborile na me."},{"v":5,"t":"TÓa, kraj svježe trave njače li magarac, muče li goveče kraj punih jasala?"},{"v":6,"t":"Zar hranu bljutavu jedemo bez soli? Zar kakove slasti ima u bjelancu?"},{"v":7,"t":"Al' ono što mi se gadilo dotaći, to mi je sada sva hrana u bolesti."},{"v":8,"t":"O, da bi se molba moja uslišala, da mi Bog ispuni ono čem se nadam!"},{"v":9,"t":"O, kada bi me Bog uništiti htio, kada bi mahnuo rukom da me satre!"},{"v":10,"t":"Za mene bi prava utjeha to bila, klicati bih mog'o u mukama teškim što se ne protivljah odluci Svetoga."},{"v":11,"t":"Zar snage imam da mogu čekati? Radi kakve svrhe da ja duže živim?"},{"v":12,"t":"Zar je snaga moja k'o snaga kamena, zar je tijelo moje od mjedi liveno?"},{"v":13,"t":"Na što se u sebi osloniti mogu? Zar mi svaka pomoć nije uskraćena?"},{"v":14,"t":"Tko odbija milost bližnjemu svojemu, prezreo je strah od Boga Svesilnoga."},{"v":15,"t":"Kao potok me iznevjeriše braća, kao bujice zimske svoje korito."},{"v":16,"t":"Od leda mutne vode im se nadimlju, 'bujaju od snijega što se topit' stao;"},{"v":17,"t":"al u doba sušno naskoro presahnu, od žege ishlape tada iz korita."},{"v":18,"t":"Karavane zbog njih skreću sa putova, u pustinju zađu i u njoj se gube."},{"v":19,"t":"Karavane temske očima ih traže, putnici iz Šebe nadaju se njima."},{"v":20,"t":"A kad do njih dođu, nađu se u čudu, jer su se u nadi svojoj prevarili."},{"v":21,"t":"U ovom ste času i vi meni takvi: vidjeste strahotu pa se preplašiste."},{"v":22,"t":"Rekoh li vam možda: 'Darujte mi štogod, poklonite nešto od svojega blaga;"},{"v":23,"t":"iz šake dušmanske izbavite mene, oslobodite me silnikova jarma?'"},{"v":24,"t":"Vi me poučite, pa ću ušutjeti, u čem je moj prijestup, pokažite meni."},{"v":25,"t":"O, kako su snažne besjede iskrene! Al' kamo to vaši smjeraju prijekori?"},{"v":26,"t":"Mislite li možda prekoriti riječi? TÓa u vjetar ide govor očajnikov!"},{"v":27,"t":"Nad sirotom kocku zar biste bacali i sa prijateljem trgovali svojim?"},{"v":28,"t":"U oči me sada dobro pogledajte, paz'te neću li vam slagati u lice."},{"v":29,"t":"Povucite riječ! Kakve li nepravde! Povucite riječ, neporočan ja sam!"},{"v":30,"t":"Zar pakosti ima na usnama mojim? Zar nesreću svaku okusio nisam?"}]},"7":{"hr":[{"v":1,"t":"Nije l' vojska život čovjekov na zemlji? Ne provodi l' dane poput najamnika?"},{"v":2,"t":"Kao što trudan rob za hladom žudi, poput nadničara štono plaću čeka,"},{"v":3,"t":"mjeseci jada tako me zapadoše i noći su mučne meni dosuđene."},{"v":4,"t":"Liježuć' mislim svagda: 'Kada ću ustati?' A dižuć se: 'Kada večer dočekati!' I tako se kinjim sve dok se ne smrkne."},{"v":5,"t":"PÓut moju crvi i blato odjenuše, koža na meni puca i raščinja se."},{"v":6,"t":"Dani moji brže od čunka prođoše, promakoše hitro bez ikakve nade."},{"v":7,"t":"Spomeni se: život moj je samo lahor i oči mi neće više vidjet' sreće!"},{"v":8,"t":"Prijateljsko oko neće me gledati; pogled svoj u mene upro si te sahnem."},{"v":9,"t":"Kao što se oblak gubi i raspline, tko u Šeol siđe, više ne izlazi."},{"v":10,"t":"Domu svome natrag ne vraća se nikad, njegovo ga mjesto više ne poznaje."},{"v":11,"t":"Ustima ja svojim stoga branit' neću, u tjeskobi duha govorit ću sada, u gorčini duše ja ću zajecati."},{"v":12,"t":"Zar sam more ili neman morska, pa si stražu nada mnom stavio?"},{"v":13,"t":"Kažem li: 'Na logu ću se smirit', ležaj će mi olakšati muke',"},{"v":14,"t":"snovima me prestravljuješ tada, prepadaš me viđenjima mučnim."},{"v":15,"t":"Kamo sreće da mi se zadavit'! Smrt mi je od patnja mojih draža."},{"v":16,"t":"Ja ginem i vječno živjet neću; pusti me, tek dah su dani moji!"},{"v":17,"t":"Što je čovjek da ga toliko ti cijeniš, da je srcu tvojem tako prirastao"},{"v":18,"t":"i svakoga jutra da njega pohodiš i svakoga trena da ga iskušavaš?"},{"v":19,"t":"Kada ćeš svoj pogled skinuti sa mene i dati mi barem pljuvačku progutat'?"},{"v":20,"t":"Ako sam zgriješio, što učinih tebi, o ti koji pomno nadzireš čovjeka? Zašto si k'o metu mene ti uzeo, zbog čega sam tebi na teret postao?"},{"v":21,"t":"Zar prijestupa moga ne možeš podnijeti i ne možeš prijeći preko krivnje moje? Jer, malo će proći i u prah ću leći, ti ćeš me tražiti, al' me biti neće.”"}]},"8":{"hr":[{"v":1,"t":"Bildan iz Šuaha progovori tad i reče:"},{"v":2,"t":"“Dokad ćeš jošte govoriti tako, dokle će ti riječ kao vihor biti?"},{"v":3,"t":"TÓa zar može Bog pravo pogaziti, može li pravdu izvrnut' Svesilni?"},{"v":4,"t":"Ako mu djeca tvoja sagriješiše, preda ih zato bezakonju njinu."},{"v":5,"t":"Al' ako Boga potražiš iskreno i od Svesilnog milost ti izmoliš;"},{"v":6,"t":"ako li budeš čist i neporočan, odsad će svagda on nad tobom bdjeti i obnovit će kuću pravedniku."},{"v":7,"t":"Bit će malena tvoja sreća prošla prema budućoj što te očekuje."},{"v":8,"t":"No pitaj samo prošle naraštaje, na mudrost pređa njihovih pripazi."},{"v":9,"t":"Od jučer mi smo i ništa ne znamo, poput sjene su na zemlji nam dani."},{"v":10,"t":"Oni će te poučit' i reći ti, iz srca će svog izvući besjede:"},{"v":11,"t":"'Izvan močvare zar će rogoz nići? Zar će bez vode trstika narasti?"},{"v":12,"t":"Zeleni se sva, al' i nekošena usahne prije svake druge trave."},{"v":13,"t":"To je kob svakog tko Boga zaboravi; tako propada nada bezbožnika:"},{"v":14,"t":"Nit je tanana njegovo uzdanje, a ufanje mu kuća paukova."},{"v":15,"t":"Nasloni li se, ona mu se ljulja, prihvati li se, ona mu se ruši."},{"v":16,"t":"Zeleni se i sav na suncu buja, vrt su mu cio mladice prerasle."},{"v":17,"t":"Svojim korijenjem krš je isprepleo te život crpe iz živa kamena."},{"v":18,"t":"A kad ga s mjesta njegova istrgnu, ono ga niječe: 'Nikada te ne vidjeh!'"},{"v":19,"t":"I evo gdje na putu sada trune dok drugo bilje već niče iz zemlje."},{"v":20,"t":"Ne, Bog neće odbacit' neporočne, niti će rukom poduprijet' opake."},{"v":21,"t":"Smijeh će ti opet ispuniti usta, s usana će odjeknuti klicanje."},{"v":22,"t":"Dušmane će ti odjenut' sramota i šatora će nestat' zlikovačkog.'”"}]},"9":{"hr":[{"v":1,"t":"Job progovori i reče:"},{"v":2,"t":"“Zaista, dobro ja znadem da je tako: kako da pred Bogom čovjek ima pravo?"},{"v":3,"t":"Ako bi se tkogod htio prÓeti s njime, odvratio mu ne bi ni jednom od tisuću."},{"v":4,"t":"Srcem on je mudar, a snagom svesilan, i tko bi se njemu nekažnjeno opro?"},{"v":5,"t":"On brda premješta, a ona to ne znaju, u jarosti svojoj on ih preokreće."},{"v":6,"t":"Pokreće on zemlju sa njezina mjesta, iz temelja njene potresa stupove."},{"v":7,"t":"Kad zaprijeti suncu, ono se ne rađa, on pečatom svojim i zvijezde pečati."},{"v":8,"t":"Jedini on je nebesa razapeo i pučinom morskom samo on hodao."},{"v":9,"t":"Stvorio je Medvjede i Oriona, Vlašiće i zvijezđa na južnome nebu."},{"v":10,"t":"Tvorac on je djela silnih, nepojmljivih čudesa koja se izbrojit' ne mogu."},{"v":11,"t":"Ide pored mene, a ja ga ne vidim; evo, on prolazi - ja ga ne opažam."},{"v":12,"t":"Ugrabi li što, tko će mu to priječit, i tko ga pitat smije: 'Što si učinio?'"},{"v":13,"t":"Bog silni srdžbu svoju ne opoziva: pred njim poniču saveznici Rahaba."},{"v":14,"t":"Pa kako onda da njemu odgovorim, koju riječ da protiv njega izaberem?"},{"v":15,"t":"I da sam u pravu, odvratio ne bih, u suca svojega milost bih molio."},{"v":16,"t":"A kad bi se na zov moj i odazvao, vjerovao ne bih da on glas moj sluša."},{"v":17,"t":"Jer, za dlaku jednu on mene satire, bez razloga moje rane umnožava."},{"v":18,"t":"Ni časa jednoga predahnut' mi ne da, nego mene svakom gorčinom napaja!"},{"v":19,"t":"Ako je na snagu - tÓa on je najjači! Ako je na pravdu - tko će njega na sud?"},{"v":20,"t":"Da sam i prav, usta bi me osudila, da sam i nevin, zlim bi me proglasila."},{"v":21,"t":"A jesam li nevin? Ni sam ne znam više, moj je život meni sasvim omrzao!"},{"v":22,"t":"Jer, to je svejedno; i zato ja kažem: nevina i grešnika on dokončava."},{"v":23,"t":"I bič smrtni kad bi odjednom ubijo ... ali on se ruga nevolji nevinih."},{"v":24,"t":"U zemlji predanoj u šake zlikovaca, on oči sucima njezinim zastire. Ako on to nije, tko je drugi onda?"},{"v":25,"t":"Od skoroteče su brži moji dani, bježe daleko, nigdje dobra ne videć.'"},{"v":26,"t":"K'o čamci od rogoza hitro promiču, k'o orao na plijen kada se zaleti."},{"v":27,"t":"Kažem li: zaboravit ću jadikovku, razvedrit ću lice i veseo biti,"},{"v":28,"t":"od mojih me muka groza obuzima, jer znadem da me ti ne držiš nevinim."},{"v":29,"t":"Ako li sam grešan, tÓa čemu onda da zalud mučim sebe."},{"v":30,"t":"Kad bih i sniježnicom sebe ja isprao, kad bih i lugom ruke svoje umio,"},{"v":31,"t":"u veću bi me nečist opet gurnuo, i moje bi me se gnušale haljine!"},{"v":32,"t":"Nije čovjek k'o ja da se s njime pravdam i na sud da idem s njim se parničiti."},{"v":33,"t":"Niti kakva suca ima među nama da ruke svoje stavi na nas dvojicu,"},{"v":34,"t":"da šibu njegovu od mene odmakne, da užas njegov mene više ne plaši!"},{"v":35,"t":"Govorit ću ipak bez ikakva straha, jer ja nisam takav u svojim očima!"}]},"10":{"hr":[{"v":1,"t":"Kad mi je duši život omrznuo, nek' mi tužaljka poteče slobodno, zborit ću u gorčini duše svoje."},{"v":2,"t":"Reću ću Bogu: Nemoj me osudit! Kaži mi zašto se na me obaraš."},{"v":3,"t":"TÓa što od toga imaš da me tlačiš, da djelo ruku svojih zabacuješ, da pomažeš namjerama opakih?"},{"v":4,"t":"Jesu li u tebe oči tjelesne? Zar ti vidiš kao što čovjek vidi?"},{"v":5,"t":"Zar su ti dani k'o dani smrtnika a kao ljudski vijek tvoje godine?"},{"v":6,"t":"Zbog čega krivnju moju istražuješ i grijehe moje hoćeš razotkriti,"},{"v":7,"t":"kad znadeš dobro da sam nedužan, da ruci tvojoj izmaknut ne mogu?"},{"v":8,"t":"Tvoje me ruke sazdaše, stvoriše, zašto da me sada opet raščiniš!"},{"v":9,"t":"Sjeti se, k'o glinu si me sazdao i u prah ćeš me ponovo vratiti."},{"v":10,"t":"Nisi li mene k'o mlijeko ulio i učinio da se k'o sir zgrušam?"},{"v":11,"t":"Kožom si me i mesom odjenuo, kostima si me spleo i žilama."},{"v":12,"t":"S milošću si mi život darovao, brižljivo si nad mojim bdio dahom."},{"v":13,"t":"Al' u svom srcu ovo si sakrio, znam da je tvoja to bila namjera:"},{"v":14,"t":"da paziš budno hoću li zgriješiti i da mi grijeh ne prođe nekažnjeno."},{"v":15,"t":"Ako sam grešan, onda teško meni, ako li sam prav, glavu ne smijem dići - shrvan sramotom, nesrećom napojen!"},{"v":16,"t":"Ispravim li se, k'o lav me nagoniš, snagu svoju okušavaš na meni,"},{"v":17,"t":"optužbe nove na mene podižeš, jarošću većom na mene usplamtiš i sa svježim se četama obaraš."},{"v":18,"t":"Iz utrobe što si me izvukao? O, što ne umrijeh: vidjeli me ne bi,"},{"v":19,"t":"bio bih k'o da me ni bilo nije, iz utrobe u grob bi me stavili."},{"v":20,"t":"Mog su života dani tako kratki! Pusti me da se još malo veselim"},{"v":21,"t":"prije nego ću na put bez povratka, u zemlju tame, zemlju sjene smrtne,"},{"v":22,"t":"u zemlju tmine guste i meteža, gdje je svjetlost slična noći najcrnjoj.”"}]},"11":{"hr":[{"v":1,"t":"Sofar iz Naama progovori tad i reče:"},{"v":2,"t":"“Zar na riječi mnoge da se ne odvrati? Zar će se brbljavac još i opravdati?"},{"v":3,"t":"Zar će tvoje trice ušutkati ljude, zar će ruganje ostat' neizrugano?"},{"v":4,"t":"Rekao si: 'Nauk moj je neporočan, u očima tvojim čist sam i bez ljage.'"},{"v":5,"t":"Ali kada bi Bog htio progovorit' i otvorit usta da ti odgovori"},{"v":6,"t":"kada bi ti tajne mudrosti otkrio koje um nijedan ne može doumit', znao bi da ti za grijehe račun ište."},{"v":7,"t":"Možeš li dubine Božje proniknuti, dokučiti savršenstvo Svesilnoga?"},{"v":8,"t":"Od neba je više: što još da učiniš? Od Šeola dublje: što još da mudruješ?"},{"v":9,"t":"Duže je od zemlje - šire je od mora!"},{"v":10,"t":"Ako se povuče, ako te pograbi, ako na sud preda, tko će mu braniti?"},{"v":11,"t":"Jer on u čovjeku prozire prijevaru, vidi opačinu ako i ne gleda."},{"v":12,"t":"Čovjek se bezuman obraća k pameti i divlji magarac uzdi se pokori."},{"v":13,"t":"Ako li srce svoje ti uspraviš i ruke svoje pružiš prema njemu,"},{"v":14,"t":"ako li zloću iz ruku odbaciš i u šatoru svom ne daš zlu stana,"},{"v":15,"t":"čisto ćeš čelo moći tad podići, čvrst ćeš biti i bojati se nećeš."},{"v":16,"t":"Svojih se kušnja nećeš sjećat' više kao ni vode koja je protekla."},{"v":17,"t":"Jasnije će tvoj život sjat' no podne, tmina će se obratit' u svanuće."},{"v":18,"t":"U uzdanju svom živjet ćeš sigurno i zaštićen počivat ćeš u miru."},{"v":19,"t":"Kad legneš, nitko te buniti neće; mnogi će tvoju tražiti naklonost."},{"v":20,"t":"A zlikovcima ugasnut će oči, neće im više biti utočišta: izdahnut', bit će jedina im nada.”"}]},"12":{"hr":[{"v":1,"t":"Job progovori i reče:"},{"v":2,"t":"“Uistinu, vi ste cvijet naroda, sa vama će izumrijeti mudrost."},{"v":3,"t":"Al' i ja znam k'o i vi misliti, ni u čemu od vas gori nisam: tko za stvari takve ne bi znao?"},{"v":4,"t":"Prijateljima sam svojim ja na podsmijeh što zazivam Boga da mi odgovori! Na podsmijeh ja sam - pravednik neporočan!"},{"v":5,"t":"Prezirat' je nesretnika - sretni misle, udariti treba onog što posrće!"},{"v":6,"t":"Dotle su na miru šatori pljačkaša, izazivači Boga žive bezbrižno kao da Boga u šaci svojoj drže!"},{"v":7,"t":"Ali pitaj zvijeri, i poučit će te; ptice nebeske pitaj, i razjasnit će ti."},{"v":8,"t":"Gušteri zemlje to će ti protumačit', ribe u moru ispripovjedit će ti."},{"v":9,"t":"Od stvorenja sviju, koje ne bi znalo da je sve to Božja ruka učinila?!"},{"v":10,"t":"U ruci mu leži život svakog bića i dah životvorni svakog ljudskog tijela."},{"v":11,"t":"Zar uhom mi ne sudimo besjedu k'o što kušamo nepcem okus jela?"},{"v":12,"t":"Sjedine mudrost donose čovjeku, a s vijekom dugim umnost mu dolazi."},{"v":13,"t":"Ali u Njemu mudrost je i snaga, u Njemu savjet je i sva razumnost."},{"v":14,"t":"Što razgradi, sagradit neće nitko, kog zatvori, nitko ne oslobađa."},{"v":15,"t":"Ustavi li vodu, suša nastaje; pusti li je, svu zemlju ispremetne."},{"v":16,"t":"Jer u njemu je snaga i sva mudrost, njegov je prevareni i varalica."},{"v":17,"t":"On savjetnike lišava razbora, suce pametne udara bezumljem."},{"v":18,"t":"On otpasuje pojas kraljevima i užetom im vezuje bokove."},{"v":19,"t":"On bosonoge tjera svećenike i mogućnike sa vlasti obara."},{"v":20,"t":"On diže riječ iz usta rječitima i starcima pravo rasuđivanje."},{"v":21,"t":"On sasiplje prezir po plemićima i junacima bedra raspasuje."},{"v":22,"t":"On dubinama razotkriva tmine i sjenu smrtnu na svjetlo izvodi."},{"v":23,"t":"On diže narod pa ga uništava, umnoži ga a potom iskorijeni."},{"v":24,"t":"On zaluđuje vladare naroda te po bespuću lutaju pustinjskom"},{"v":25,"t":"i pipaju u tmini bez svjetlosti glavinjajući poput pijanaca."}]},"13":{"hr":[{"v":1,"t":"Očima svojim sve to ja vidjeh, ušima svojim čuh i razumjeh."},{"v":2,"t":"Sve što vi znate znadem to i ja, ni u čemu od vas gori nisam."},{"v":3,"t":"Zato, zborit' moram sa Svesilnim, pred Bogom svoj razlog izložiti."},{"v":4,"t":"Jer, kovači laži vi ste pravi, i svi ste vi zaludni liječnici!"},{"v":5,"t":"Kada biste bar znali šutjeti, mudrost biste svoju pokazali!"},{"v":6,"t":"Dokaze mi ipak poslušajte, razlog mojih usana počujte."},{"v":7,"t":"Zar zbog Boga govorite laži, zar zbog njega riječi te prijevarne?"},{"v":8,"t":"Zar biste pristrano branit' htjeli Boga, zar biste mu htjeli biti odvjetnici?"},{"v":9,"t":"Zar bi dobro bilo da vas on ispita? Zar biste ga obmanuli k'o čovjeka?"},{"v":10,"t":"Kaznom preteškom on bi vas pokarao poradi potajne vaše pristranosti."},{"v":11,"t":"Zar vas veličanstvo njegovo ne plaši i zar vas od njega užas ne spopada?"},{"v":12,"t":"Razlozi su vam od pepela izreke, obrana je vaša obrana od blata."},{"v":13,"t":"Umuknite sada! Dajte da govorim, pa neka me poslije snađe što mu drago."},{"v":14,"t":"Zar da meso svoje sam kidam zubima? Da svojom rukom život upropašćujem?"},{"v":15,"t":"On me ubit' može: nade druge nemam već da pred njim svoje držanje opravdam."},{"v":16,"t":"I to je već zalog mojega spasenja, jer bezbožnik preda nj ne može stupiti."},{"v":17,"t":"Pažljivo mi riječi poslušajte, nek' vam prodre u uši besjeda."},{"v":18,"t":"Gle: ja sam pripremio parnicu, jer u svoje sam pravo uvjeren."},{"v":19,"t":"Tko se sa mnom hoće parničiti? - Umuknut ću potom te izdahnut'."},{"v":20,"t":"Dvije mi molbe samo ne uskrati da se od tvog lica ne sakrivam:"},{"v":21,"t":"digni s mene tešku svoju ruku i užasom svojim ne straši me."},{"v":22,"t":"Tada me pitaj, a ja ću odgovarat'; ili ja da pitam, ti da odgovaraš."},{"v":23,"t":"Koliko počinih prijestupa i grijeha? Prekršaj mi moj pokaži i krivicu."},{"v":24,"t":"Zašto lice svoje kriješ sad od mene, zašto u meni vidiš neprijatelja?"},{"v":25,"t":"Zašto strahom mučiš list vjetrom progonjen, zašto se na suhu obaraš slamčicu?"},{"v":26,"t":"O ti, koji mi gorke pišeš presude i teretiš mene grijesima mladosti,"},{"v":27,"t":"koji si mi noge u klade sapeo i koji bdiš nad svakim mojim korakom i tragove stopa mojih ispituješ!"},{"v":28,"t":"Život mi se k'o trulo drvo raspada, k'o haljina što je moljci izjedaju!"}]},"14":{"hr":[{"v":1,"t":"Čovjek koga je žena rodila kratka je vijeka i pun nevolja."},{"v":2,"t":"K'o cvijet je nikao i vene već, poput sjene bježi ne zastajuć'."},{"v":3,"t":"Na takva, zar, ti oči otvaraš i preda se na sud ga izvodiš?"},{"v":4,"t":"Tko će čisto izvuć' iz nečista? Nitko!"},{"v":5,"t":"Pa kad su njegovi dani odbrojeni, kad mu broj mjeseci o tebi ovisi, kad mu granicu stavljaš neprijelaznu,"},{"v":6,"t":"skini s njega pogled da počinut' može, poput najamnika da svoj dan uživa."},{"v":7,"t":"TÓa ni drvu nije nada sva propala, posječeno, ono opet prozeleni i mladice nove iz njega izbiju."},{"v":8,"t":"Ako mu korijen i ostari u zemlji, ako mu se panj i sasuši u prahu,"},{"v":9,"t":"oćutjevši vodu, ono će propupat' i pustiti grane kao stablo novo."},{"v":10,"t":"Al' kad čovjek umre, ostaje pokošen, kad smrtnik izdahne, gdje li je on tada?"},{"v":11,"t":"Može sva voda iz mora ispariti i presahnut' rijeke, isušit posvema',"},{"v":12,"t":"al' čovjek kad legne, ne ustaje više, dok nebesa bude, neće se podići, od sna se svojega probuditi neće."},{"v":13,"t":"O, kad bi me htio skriti u Šeolu, zakloniti me dok srdžba ti ne mine, dÓati mi rok kad ćeš me se spomenuti,"},{"v":14,"t":"- jer, kad umre čovjek, zar uskrsnut' može? - čekao bih te sve dane vojske svoje dok ne bi došao da mi smjenu dadeš."},{"v":15,"t":"Zvao bi me, a ja bih se odazvao: zaželio si se djela svojih ruku."},{"v":16,"t":"A sad nad svakim mojim vrebaš korakom, nijednog mi grijeha nećeš oprostiti,"},{"v":17,"t":"u vreći si prijestup moj zapečatio i krivicu moju svu si zapisao."},{"v":18,"t":"Vaj! K'o što se jednom uruši planina, k'o što se hridina s mjesta svog odvali,"},{"v":19,"t":"k'o što voda kamen s vremenom istroši, a pljusak bujicom zemlju svu sapere, tako uništavaš nadu u čovjeku."},{"v":20,"t":"Oborio si ga - on ode za svagda, nagrđena lica, otjeran, odbačen."},{"v":21,"t":"Djecu mu poštuju - o tom ništa ne zna; ako su prezrena - o tom ne razmišlja."},{"v":22,"t":"On jedino pati zbog svojega tijela, on jedino tuži zbog svojeg života.”"}]},"15":{"hr":[{"v":1,"t":"Elifaz Temanac progovori tad i reče:"},{"v":2,"t":"“Zar šupljom naukom odgovara mudrac i vjetrom istočnim trbuh napuhuje?"},{"v":3,"t":"Zar on sebe brani riječima ispraznim, besjedama koje ničem ne koriste?"},{"v":4,"t":"Još više ti činiš: ništiš strah od Boga, pred njegovim licem pribranost ukidaš."},{"v":5,"t":"Tvoje riječi krivicu tvoju odaju, poslužio si se jezikom lukavih,"},{"v":6,"t":"vlastita te usta osuđuju, ne ja, protiv tebe same ti usne svjedoče."},{"v":7,"t":"Zar si prvi čovjek koji se rodio? Zar si na svijet prije bregova došao?"},{"v":8,"t":"Zar si tajne Božje ti prisluškivao i mudrost čitavu za se prisvojio?"},{"v":9,"t":"Što ti znadeš, a da i mi ne znamo, što ti razumiješ, a da to ne shvaćamo?"},{"v":10,"t":"Ima među nama i sijedih i starih kojima je više ljeta no tvom ocu."},{"v":11,"t":"Zar su ti utjehe Božje premalene i blage riječi upućene tebi?"},{"v":12,"t":"Što te srce tvoje tako slijepo goni i što tako divlje prevrćeš očima"},{"v":13,"t":"kad proti Bogu jarost svoju okrećeš, a iz usta takve riječi ti izlaze!"},{"v":14,"t":"Što je čovjek da bi čist mogao biti? Zar je itko rođen od žene pravedan?"},{"v":15,"t":"Gle, ni u svece se On ne pouzdava, oku njegovu ni nebesa čista nisu,"},{"v":16,"t":"a kamoli to biće gadno i buntovno, čovjek što k'o vodu pije opačinu!"},{"v":17,"t":"Mene sad poslušaj, poučit' te hoću, što god sam vidjeh, ispričat' ti želim,"},{"v":18,"t":"i ono što naučavahu mudraci ne tajeć' što su primili od pređa"},{"v":19,"t":"kojima je zemlja ova bila dana kamo tuđin nije nikada stupio."},{"v":20,"t":"Zlikovac se muči cijelog svoga vijeka, nasilniku već su ljeta odbrojena."},{"v":21,"t":"Krik strave svagda mu u ušima ječi, dok miruje, na njeg baca se razbojnik."},{"v":22,"t":"Ne nada se da će izbjeći tminama i znade dobro da je maču namijenjen,"},{"v":23,"t":"strvinaru da je kao plijen obećan. On znade da mu se dan propasti bliži."},{"v":24,"t":"Nemir i tjeskoba na njeg navaljuju, k'o kralj spreman na boj na nj se obaraju."},{"v":25,"t":"On je protiv Boga podizao ruku, usuđivao se prkosit' Svesilnom"},{"v":26,"t":"Ohola je čela na njega srljao, iza štita debela dobro zaklonjen."},{"v":27,"t":"Lice mu bijaše obloženo salom a bokovi pretilinom otežali."},{"v":28,"t":"Razrušene je zaposjeo gradove i kućišta nastanio napuštena. Srušit će se ono što za sebe sazda;"},{"v":29,"t":"cvasti mu neće, već rasuti se blago, sjena mu se neće po zemlji širiti."},{"v":30,"t":"On se tami više izmaknuti neće, opržit će oganj njegove mladice, u dahu plamenih usta nestat će ga."},{"v":31,"t":"U taštinu svoju neka se ne uzda, jer će mu ispraznost biti svom nagradom."},{"v":32,"t":"Prije vremena će svenut' mu mladice, grane mu se nikad neće zazelenjet'."},{"v":33,"t":"Kao loza, grozd će stresat' svoj nezreo, poput masline pobacit će cvatove."},{"v":34,"t":"Da, bezbožničko je jalovo koljeno, i vatra proždire šator podmitljivca."},{"v":35,"t":"Koji zlom zanesu, rađaju nesreću i prijevaru nose u utrobi svojoj.”"}]},"16":{"hr":[{"v":1,"t":"Job progovori i reče:"},{"v":2,"t":"“Koliko se takvih naslušah besjeda, kako ste mi svi vi mučni tješioci!"},{"v":3,"t":"Ima li kraja tim riječima ispraznim? Što te goni da mi tako odgovaraš?"},{"v":4,"t":"I ja bih mogao k'o vi govoriti da vam je duša na mjestu duše moje; i ja bih vas mog'o zasuti riječima i nad sudbom vašom tako kimat' glavom;"},{"v":5,"t":"i ja bih mogao ustima vas hrabrit', i ne bih žalio trud svojih usana."},{"v":6,"t":"Al' ako govorim, patnja se ne blaži, ako li zašutim, zar će me minuti?"},{"v":7,"t":"Zlopakost me sada shrvala posvema, čitava se rulja oborila na me."},{"v":8,"t":"Ustao je proti meni da svjedoči i u lice mi se baca klevetama."},{"v":9,"t":"Jarošću me svojom razdire i goni, škrgućuć' zubima obara se na me. Moji protivnici sijeku me očima,"},{"v":10,"t":"prijeteći, na mene usta razvaljuju, po obrazima me sramotno ćuškaju, u čoporu svi tad navaljuju na me."},{"v":11,"t":"Da, zloćudnicima Bog me predao, u ruke opakih on me izručio."},{"v":12,"t":"Mirno življah dok On ne zadrma mnome, za šiju me ščepa da bi me slomio."},{"v":13,"t":"Uze me za biljeg i strijelama osu, nemilosrdno mi bubrege probode i mojom žuči zemlju žednu natopi."},{"v":14,"t":"Na tijelu mi ranu do rane otvara, kao bijesan ratnik nasrće na mene."},{"v":15,"t":"Tijelo sam golo u kostrijet zašio, zario sam čelo svoje u prašinu."},{"v":16,"t":"Zapalilo mi se sve lice od suza, sjena tamna preko vjeđa mi je pala."},{"v":17,"t":"A nema nasilja na rukama mojim, molitva je moja bila uvijek čista."},{"v":18,"t":"O zemljo, krvi moje nemoj sakriti i kriku mom ne daj nigdje da počine."},{"v":19,"t":"Odsad na nebu imam ja svjedoka, u visini gore moj stoji branitelj."},{"v":20,"t":"Moja vika moj je odvjetnik kod Boga dok se ispred njega suze moje liju:"},{"v":21,"t":"o, da me obrani u parbi mojoj s Bogom ko što smrtnik brani svojega bližnjega."},{"v":22,"t":"No životu mom su odbrojena ljeta, na put bez povratka meni je krenuti."}]},"17":{"hr":[{"v":1,"t":"Daha mi nestaje, gasnu moji dani i za mene već se skupljaju grobari."},{"v":2,"t":"Rugači su evo mene dohvatili, od uvreda oka sklopiti ne mogu."},{"v":3,"t":"Stoga me zaštiti i budi mi jamcem kad mi nitko u dlan neće da udari."},{"v":4,"t":"Jer, srca si njina lišio razuma i dopustiti im nećeš da opstanu."},{"v":5,"t":"K'o taj što imanje dijeli drugovima, a djeci njegovoj dotle oči gasnu,"},{"v":6,"t":"narodima svim sam na ruglo postao, onaj kom u lice svatko pljunut' može."},{"v":7,"t":"Od tuge vid mi se muti u očima, poput sjene moji udovi postaju."},{"v":8,"t":"Začudit će se zbog toga pravednici, na bezbožnika će planuti čestiti;"},{"v":9,"t":"neporočni će na svom ustrajat' putu, čovjek čistih ruku ojačat će još više."},{"v":10,"t":"Hajde, svi vi, nećete li opet počet', tÓa među vama ja mudra ne nalazim!"},{"v":11,"t":"Minuli su dani, propale zamisli, želje srca moga izjalovile se."},{"v":12,"t":"'U noći najcrnjoj, dan se približava; blizu je već svjetlo što tminu izgoni.'"},{"v":13,"t":"A meni je nada otići u Šeol i prostrijeti sebi ležaj u mrklini."},{"v":14,"t":"Dovikujem grobu: 'Oče moj rođeni!' a crve pozdravljam: 'Mati moja, sestro!'"},{"v":15,"t":"Ali gdje za mene ima jošte nade? Sreću moju tko će ikada vidjeti?"},{"v":16,"t":"Hoće li u Šeol ona sa mnom sići da u prahu zajedno otpočinemo?”"}]},"18":{"hr":[{"v":1,"t":"Bildad iz Šuaha progovori tad i reče:"},{"v":2,"t":"“Kada kaniš obuzdat' svoje besjede? Opameti se sad da razgovaramo!"},{"v":3,"t":"Zašto nas držiš za stoku nerazumnu, zar smo životinje u tvojim očima?"},{"v":4,"t":"O ti, koji se od jarosti razdireš, hoćeš li da zemlja zbog tebe opusti da iz svoga mjesta iskoče pećine?"},{"v":5,"t":"Al' ugasit će se svjetlost opakoga, i neće mu sjati plamen na ognjištu."},{"v":6,"t":"Potamnjet će svjetlo u njegovu šatoru i nad njime će se utrnut' svjetiljka."},{"v":7,"t":"Krepki mu koraci postaju sputani, o vlastite on se spotiče namjere."},{"v":8,"t":"Jer njegove noge vode ga u zamku, i evo ga gdje već korača po mreži."},{"v":9,"t":"Tanka mu je zamka nogu uhvatila, i evo, užeta čvrsto ga pritežu."},{"v":10,"t":"Njega vreba omča skrivena na zemlji, njega čeka klopka putem kojim hodi."},{"v":11,"t":"Odasvuda strahovi ga prepadaju, ustopice sveudilj ga proganjaju."},{"v":12,"t":"Glad je požderala svu snagu njegovu, nesreća je uvijek o njegovu boku."},{"v":13,"t":"Boleština kobna kožu mu razjeda, prvenac mu smrti nagriza udove."},{"v":14,"t":"Njega izvlače iz šatora njegova da bi ga odveli vladaru strahota."},{"v":15,"t":"U njegovu stanu tuđinac stanuje, po njegovu domu prosipaju sumpor."},{"v":16,"t":"Odozdo se suši njegovo korijenje, a odozgo grane sve mu redom sahnu."},{"v":17,"t":"Spomen će se njegov zatrti na zemlji, njegovo se ime s lica zemlje briše."},{"v":18,"t":"Iz svjetlosti njega u tminu tjeraju, izagnat' ga hoće iz kruga zemaljskog."},{"v":19,"t":"U rodu mu nema roda ni poroda, nit' preživjela na njegovu ognjištu."},{"v":20,"t":"Sudba je njegova Zapad osupnula, i čitav je Istok obuzela strepnja."},{"v":21,"t":"Evo, takav usud snalazi zlikovca i dom onog koji ne priznaje Boga.”"}]},"19":{"hr":[{"v":1,"t":"Job progovori i reče:"},{"v":2,"t":"“TÓa dokle ćete mučit' dušu moju, dokle ćete me riječima satirat'?"},{"v":3,"t":"Već deseti put pogrdiste mene i stid vas nije što me zlostavljate."},{"v":4,"t":"Pa ako sam zastranio doista, na meni moja zabluda ostaje."},{"v":5,"t":"Mislite li da ste me nadjačali i krivnju moju da ste dokazali?"},{"v":6,"t":"Znajte: Bog je to mene pritisnuo i svojom me je on stegnuo mrežom."},{"v":7,"t":"Vičem: 'Nasilje!' - nema odgovora; vapijem - ali za me pravde nema."},{"v":8,"t":"Sa svih strana put mi je zagradio, sve staze moje u tminu zavio."},{"v":9,"t":"Slavu je moju sa mene skinuo, sa moje glave strgnuo je krunu."},{"v":10,"t":"Podsijeca me odasvud te nestajem; k'o drvo, nadu mi je iščupao."},{"v":11,"t":"Raspalio se gnjev njegov na mene i svojim me drži neprijateljem."},{"v":12,"t":"U bojnom redu pristižu mu čete, putove proti meni nasipaju, odasvud moj opkoljavaju šator."},{"v":13,"t":"Od mene su se udaljila braća, otuđili se moji poznanici."},{"v":14,"t":"Nestade bližnjih mojih i znanaca, gosti doma mog zaboraviše me."},{"v":15,"t":"Sluškinjama sam svojim kao stranac, neznanac sam u njihovim očima."},{"v":16,"t":"Slugu zovnem, a on ne odgovara i za milost ga moram zaklinjati."},{"v":17,"t":"Mojoj je ženi dah moj omrznuo, gadim se djeci vlastite utrobe."},{"v":18,"t":"I deranima na prezir tek služim, ako se dignem, rugaju se meni."},{"v":19,"t":"Pouzdanicima sam svojim mrzak, protiv mene su oni koje ljubljah."},{"v":20,"t":"Kosti mi se za kožu prilijepiše, osta mi jedva koža oko zuba."},{"v":21,"t":"Smilujte mi se, prijatelji moji, jer Božja me je ruka udarila."},{"v":22,"t":"Zašto da me k'o Bog sam progonite, zar se niste moga nasitili mesa?"},{"v":23,"t":"O, kad bi se riječi moje zapisale i kad bi se u mjed tvrdu urezale;"},{"v":24,"t":"kad bi se željeznim dlijetom i olovom u spomen vječan u stijenu uklesale!"},{"v":25,"t":"Ja znadem dobro: moj Izbavitelj živi i posljednji će on nad zemljom ustati."},{"v":26,"t":"A kad se probudim, k sebi će me dići: iz svoje ću puti tad vidjeti Boga."},{"v":27,"t":"Njega ja ću kao svojega gledati, i očima mojim neće biti stranac: za njime srce mi čezne u grudima."},{"v":28,"t":"Kad kažete: 'Kako ćemo ga goniti? Koji ćemo razlog protiv njega naći?',"},{"v":29,"t":"mača tad se bojte: grijehu mač je kazna. Saznat ćete tada da imade suda!”"}]},"20":{"hr":[{"v":1,"t":"Sofar iz Naamata progovori tad i reče:"},{"v":2,"t":"“Misli me tjeraju da ti odgovorim, i zato u meni vri to uzbuđenje"},{"v":3,"t":"dok slušam ukore koji me sramote, al' odgovor mudar um će moj već naći."},{"v":4,"t":"Zar tebi nije od davnine poznato, otkad je čovjek na zemlju stavljen bio,"},{"v":5,"t":"da je kratka vijeka radost opakoga, da kao tren prođe sreća bezbožnička."},{"v":6,"t":"Pa ako stasom i do neba naraste, ako mu se glava dotakne oblaka,"},{"v":7,"t":"poput utvare on zauvijek nestaje; koji ga vidješe kažu: 'Gdje je sad on?'"},{"v":8,"t":"Kao san bez traga on se rasplinjuje, nestaje ga kao priviđenja noćnog."},{"v":9,"t":"Nijedno ga oko više gledat neće, niti će ga mjesto njegovo vidjeti"},{"v":10,"t":"Njegovu će djecu gonit' siromasi: rukama će svojim vraćati oteto."},{"v":11,"t":"Kosti su njegove bujale mladošću; gle, zajedno s njome pokošen je sada."},{"v":12,"t":"Zlo bijaše slatko njegovim ustima te ga je pod svojim jezikom skrivao;"},{"v":13,"t":"sladio se pazeć' da ga ne proguta i pod nepcem svojim zadržavao ga."},{"v":14,"t":"Ali hrana ta mu trune u utrobi, otrovom zmijskim u crijevima postaje."},{"v":15,"t":"Blago progutano mora izbljuvati. Bog će ga istjerat' njemu iz utrobe."},{"v":16,"t":"Iz zmijine glave otrov je sisao: sada umire od jezika gujina."},{"v":17,"t":"Potoke ulja on gledat' više neće, ni vidjet' gdje rijekom med i mlijeko teku."},{"v":18,"t":"Vratit će dobitak ne okusivši ga, neće uživat' u plodu trgovine."},{"v":19,"t":"Jer je sirotinju gnjeo i tlačio, otimao kuće koje ne sazida,"},{"v":20,"t":"jer ne bješe kraja požudi njegovoj, njegova ga blaga neće izbaviti."},{"v":21,"t":"Jer mu proždrljivost ništa ne poštedi, ni sreća njegova dugo trajat neće."},{"v":22,"t":"Sred izobilja u škripcu će se naći, svom će snagom na nj se oboriti bijeda."},{"v":23,"t":"I dok hranom bude trbuh svoj punio, Bog će na nj pustiti jarost svoga gnjeva, sasut' dažd strelica na meso njegovo."},{"v":24,"t":"Ako i izmakne gvozdenom oružju, luk će mjedeni njega prostrijeliti."},{"v":25,"t":"Strijelu bi izvuk'o, al' mu probi leđa, a šiljak blistavi viri mu iz žuči. Kamo god krenuo, strepnje ga vrebaju,"},{"v":26,"t":"na njega tmine sve tajom očekuju. Vatra ga ništi, ni od kog zapaljena, i proždire sve pod njegovim šatorom."},{"v":27,"t":"Gle, nebo krivicu njegovu otkriva i čitava zemlja na njega se diže."},{"v":28,"t":"Njegovu će kuću raznijeti poplava, otplaviti je u dan Božje jarosti."},{"v":29,"t":"Takvu sudbinu Bog priprema zlikovcu i takvu baštinu on mu dosuđuje.”"}]},"21":{"hr":[{"v":1,"t":"Job progovori i reče:"},{"v":2,"t":"“Slušajte, slušajte dobro što ću reći, utjehu mi takvu barem udijelite."},{"v":3,"t":"Otrpite da riječ jednu ja izrečem, kad završim, tad se rugajte slobodno."},{"v":4,"t":"Zar protiv čovjeka dižem ja optužbu? Kako da strpljenje onda ne izgubim?"},{"v":5,"t":"Pogledajte na me: užas će vas spopast', rukom ćete svoja zakloniti usta;"},{"v":6,"t":"pomislim li na to, prestravim se i sam i čitavim svojim tad protrnem tijelom."},{"v":7,"t":"Zašto na životu ostaju zlikovci i, što su stariji, moćniji bivaju?"},{"v":8,"t":"Potomstvo njihovo s njima napreduje a izdanci im se množe pred očima."},{"v":9,"t":"Strah nikakav kuće njihove ne mori i šiba ih Božja ostavlja na miru."},{"v":10,"t":"Njihovi bikovi plode pouzdano, krave im se tele i ne jalove se."},{"v":11,"t":"K'o jagnjad djeca im slobodno skakuću, veselo igraju njihovi sinovi."},{"v":12,"t":"Oni pjevaju uz harfe i bubnjeve i vesele se uz zvukove svirale."},{"v":13,"t":"Dane svoje završavaju u sreći, u Podzemlje oni silaze spokojno."},{"v":14,"t":"A govorili su Bogu: 'Ostavi nas, ne želimo znati za tvoje putove!"},{"v":15,"t":"TÓa tko je Svesilni da njemu služimo i kakva nam korist da ga zazivamo?'"},{"v":16,"t":"Zar svoju sreću u ruci ne imahu, makar do Njega ne drže ništa oni?"},{"v":17,"t":"Zar se luč opakog kada ugasila? Zar se na njega oborila nesreća? Zar mu u gnjevu svom On skroji sudbinu?"},{"v":18,"t":"Zar je kao slama na vjetru postao, kao pljeva koju vihor svud raznosi?"},{"v":19,"t":"Hoće l' ga kaznit' Bog u njegovoj djeci? Ne, njega nek' kazni da sam to osjeti!"},{"v":20,"t":"Vlastitim očima nek' rasap svoj vidi, neka se napije srdžbe Svesilnoga!"},{"v":21,"t":"TÓa što poslije smrti on za dom svoj mari kad će se presjeć' niz njegovih mjeseci?"},{"v":22,"t":"Ali tko će Boga učiti mudrosti, njega koji sudi najvišim bićima?"},{"v":23,"t":"Jedan umire u punom blagostanju, bez briga ikakvih, u potpunom miru,"},{"v":24,"t":"bokova od pretiline otežalih i kostiju sočne moždine prepunih."},{"v":25,"t":"A drugi umire s gorčinom u duši, nikad nikakve ne okusivši sreće."},{"v":26,"t":"Obojica leže zajedno u prahu, crvi ih jednako prekrivaju oba."},{"v":27,"t":"O, znam dobro kakve vaše su namjere, kakve zlosti protiv mene vi snujete."},{"v":28,"t":"Jer pitate: 'Gdje je kuća plemićeva, šator u kojem stanovahu opaki?'"},{"v":29,"t":"Niste li na cesti putnike pitali, zar njihovo svjedočanstvo ne primate:"},{"v":30,"t":"'Opaki je u dan nesreće pošteđen i u dan Božje jarosti veseo je.'"},{"v":31,"t":"Al' na postupcima tko će mu predbacit' i tko će mu vratit' što je počinio?"},{"v":32,"t":"A kad ga na kraju na groblje odnesu, na grobni mu humak postavljaju stražu."},{"v":33,"t":"Lake su mu grude zemlje u dolini dok za njime ide čitavo pučanstvo."},{"v":34,"t":"O, kako su vaše utjehe isprazne! Kakva su prijevara vaši odgovori!”"}]},"22":{"hr":[{"v":1,"t":"Elifaz Temanac progovori tad i reče:"},{"v":2,"t":"“Zar Bogu koristan može biti čovjek? TÓa tko je mudar, sebi samom koristi."},{"v":3,"t":"Zar je Svesilnom milost što si pravedan i zar mu je dobit što si neporočan?"},{"v":4,"t":"Ili te zbog tvoje pobožnosti kara i zato se hoće s tobom parničiti?"},{"v":5,"t":"Nije l' to zbog zloće tvoje prevelike i zbog bezakonja kojim broja nema?"},{"v":6,"t":"Od braće si brao nizašto zaloge i s golih si ljudi svlačio haljine;"},{"v":7,"t":"ti nisi žednoga vodom napojio, uskraćivao si kruh izgladnjelima;"},{"v":8,"t":"otimao si od siromaha zemlju da bi na njoj svog nastanio ljubimca;"},{"v":9,"t":"puštao si praznih ruku udovice i siročadi si satirao ruku."},{"v":10,"t":"Eto zašto tebe mreže sad sapinju, zašto te strahovi muče iznenadni."},{"v":11,"t":"Svjetlost ti mrak posta i ništa ne vidiš, vode su duboke tebe potopile."},{"v":12,"t":"Zar Bog nije u visini nebeskoj i zar zvijezdama tjeme on ne vidi?"},{"v":13,"t":"Ali ti kažeš: 'Što Bog može znati? Kroz oblak tmasti zar što razabire?"},{"v":14,"t":"Oblaci pogled njegov zaklanjaju, i rubom kruga on hoda nebeskog.'"},{"v":15,"t":"TÓa kaniš li se drevnog držat' puta kojim su išli ljudi nepravedni?"},{"v":16,"t":"Prije vremena nestadoše oni, bujica im je temelje raznijela."},{"v":17,"t":"Zborahu Bogu: 'Nas se ti ostavi! Što nam Svesilni učiniti može?'"},{"v":18,"t":"A on im je dom punio dobrima makar do njega ne držahu ništa."},{"v":19,"t":"Videć' im propast, klikću pravednici, neporočni se njima izruguju:"},{"v":20,"t":"'Gle, propadoše protivnici naši, što od njih osta, vatra im proždrije!”"},{"v":21,"t":"S Bogom ti se sprijatelji i pomiri, i vraćena će ti opet biti sreća."},{"v":22,"t":"Ded prihvati Zakon iz njegovih usta, u srce svoje riječ njegovu usadi."},{"v":23,"t":"Ako se raskajan vratiš Svesilnome i nepravdu iz svog šatora odstraniš,"},{"v":24,"t":"tad ćeš odbaciti zlato u prašinu i ofirsko blago u šljunak potočni."},{"v":25,"t":"Svesilni će postat' tvoje suho zlato, on će biti tvoje gomile srebrene."},{"v":26,"t":"Da, Svesilni bit će tvoje radovanje, i lice ćeš k Bogu dizati slobodno."},{"v":27,"t":"Molit ćeš mu se, i uslišat će tebe, ispunit ćeš što si mu zavjetovao."},{"v":28,"t":"Što god poduzeo, sve će ti uspjeti, i putove će ti obasjavat' svjetlost."},{"v":29,"t":"Jer, on ponizuje ponos oholima, dok u pomoć smjernim očima pritječe."},{"v":30,"t":"Iz nevolje on izbavlja nevinoga; i tebe će spasit' tvoje čiste ruke.”"}]},"23":{"hr":[{"v":1,"t":"Job progovori i reče:"},{"v":2,"t":"“Zar mi je i danas tužaljka buntovna? Teška mu ruka iz mene vapaj budi:"},{"v":3,"t":"o, kada bih znao kako ću ga naći, do njegova kako doprijeti prijestolja,"},{"v":4,"t":"pred njim parnicu bih svoju razložio, iz mojih bi usta navrli dokazi."},{"v":5,"t":"Rad bih znati što bi meni odvratio i razumjeti riječ što bi je rekao!"},{"v":6,"t":"Zar mu treba snage velike za raspru? Ne, dosta bi bilo da me on sasluša."},{"v":7,"t":"U protivniku bi vidio pravedna, i parnica moja tad bi pobijedila."},{"v":8,"t":"Na istok krenem li, naći ga ne mogu; pođem li na zapad, ne razabirem ga."},{"v":9,"t":"Ištem na sjeveru, al' ga ne opažam; nevidljiv je ako se k jugu okrenem."},{"v":10,"t":"Pa ipak, on dobro zna put kojim kročim! Neka me kuša: čist k'o zlato ću izići!"},{"v":11,"t":"Noga mi se stopa njegovih držala, putem sam njegovim išao ne skrećuć';"},{"v":12,"t":"slušao sam nalog njegovih usana, pohranih mu riječi u grudima svojim."},{"v":13,"t":"Al' htjedne li štogod, tko će ga odvratit'? Što zaželi dušom, to će ispuniti."},{"v":14,"t":"Izvršit će što je dosudio meni, kao i sve drugo što je odlučio!"},{"v":15,"t":"Zbog toga pred njime sav ustravljen ja sam, i što više mislim, jače strah me hvata."},{"v":16,"t":"U komade Bog mi je srce smrvio, užasom me svega prožeo Svesilni,"},{"v":17,"t":"premda nisam ni u tminama propao, ni u mraku što je lice moje zastro."}]},"24":{"hr":[{"v":1,"t":"Zašto Svesilni ne promatra vremena, a dane njegove ne vide mu vjernici?"},{"v":2,"t":"Bezbožnici pomiču granice, otimaju stado i pasu ga."},{"v":3,"t":"Sirotama odvode magarca, udovi u zalog vola dižu."},{"v":4,"t":"Siromahe tjeraju sa puta; skrivaju se ubogari zemlje."},{"v":5,"t":"K'o magarci divlji u pustinji zarana idu da plijen ugrabe: pustinja im hrani mališane."},{"v":6,"t":"Po tuđem polju oni pabirče, paljetkuju vinograd opakog."},{"v":7,"t":"Goli noće, nemaju haljine, ni pokrivača protiv studeni."},{"v":8,"t":"Oni kisnu na planinskom pljusku; bez skloništa uz hrid se zbijaju."},{"v":9,"t":"Otkidaju od sise sirotu, ubogom u zalog dijete grabe."},{"v":10,"t":"Goli hode, nemaju haljina; izgladnjeli, tuđe snoplje nose."},{"v":11,"t":"Oni mlina za ulje nemaju; ožednjeli, gaze u kacama."},{"v":12,"t":"Samrtnici hropću iz gradova, ranjenici u pomoć zazivlju. Al' na sve to Bog se oglušuje."},{"v":13,"t":"Ima onih koji mrze svjetlost: ne priznaju njezinih putova niti se staza drže njezinih."},{"v":14,"t":"Za mraka se diže ubojica, kolje ubogog i siromaha. U gluhoj se noći lopov skiće [16a] i u tmini provaljuje kuće."},{"v":15,"t":"Sumrak žudi oko preljubnika: 'Nitko me vidjet neće', kaže on i zastire velom svoje lice."},{"v":16,"t":"[16b]Za vidjela oni se skrivaju, oni neće da za svjetlost znaju."},{"v":17,"t":"Zora im je kao sjena smrtna: kad zarudi, silan strah ih hvata."},{"v":18,"t":"Prije nego svane, on već hitro bježi kloneći se puta preko vinograda. Njegova su dobra prokleta u zemlji."},{"v":19,"t":"K'o što vrućina i žega snijeg upija, tako i Podzemlje proždire grešnike."},{"v":20,"t":"Zaboravilo ga krilo što ga rodi, ime se njegovo više ne spominje: poput stabla zgromljena je opačina."},{"v":21,"t":"Ženu nerotkinju on je zlostavljao, udovici nije učinio dobra."},{"v":22,"t":"Al' Onaj što snažno hvata nasilnike, ustaje, a njima sva se nada gasi."},{"v":23,"t":"Dade mu sigurnost, i on se pouzda; okom je njegove nadzirao staze."},{"v":24,"t":"Dignu se za kratko, a onda nestanu, ruše se i kao svi drugi istrunu, posječeni kao glave klasovima.”"},{"v":25,"t":"Nije li tako? Tko će me u laž utjerat'? Tko moje riječi poništiti može?”"}]},"25":{"hr":[{"v":1,"t":"Bildad iz Šuaha progovori tad i reče:"},{"v":2,"t":"“Gospodstvo i strah u njegovoj su ruci i on stvara mir u svojim visinama."},{"v":3,"t":"Zar se njemu čete izbrojiti mogu i svjetlo njegovo nad kim ne izlazi?"},{"v":4,"t":"Pa kako da čovjek prav bude pred Bogom i od žene rođen kako da čist bude?"},{"v":5,"t":"Eto, i mjesec pred njime sjaj svoj gubi, njegovim očima zvijezde nisu čiste."},{"v":6,"t":"Što reći onda o čovjeku, tom crvu, o sinu čovjekovu, crviću jadnom?"}]},"26":{"hr":[{"v":1,"t":"Job progovori i reče:"},{"v":2,"t":"“Kako dobro znadeš pomoći nemoćnom i mišicu iznemoglu poduprijeti!"},{"v":3,"t":"Kako dobar savjet daješ neukome; baš si preveliku mudrost pokazao."},{"v":4,"t":"Kome li si ove uputio riječi i koji duh je iz tebe govorio?”"},{"v":5,"t":"Pred Bogom mrtvi pod zemljom dolje strepe, vode morske dršću i nemani njine."},{"v":6,"t":"Pred njegovim okom otkriven zja Šeol i bezdan smrti nema vela na sebi."},{"v":7,"t":"On povrh praznine Sjever razapinje, on drži zemlju o ništa obješenu."},{"v":8,"t":"On zatvara vodu u svoje oblake, a oblaci se pod njome ne prodiru."},{"v":9,"t":"On zastire puno lice mjesečevo razastirući svoj oblak preko njega."},{"v":10,"t":"On je na vodi označio kružnicu gdje prestaje svjetlost i tmine počinju."},{"v":11,"t":"Svodu se nebeskom potresu stupovi i premru od straha kada on zaprijeti."},{"v":12,"t":"Svojom je snagom on ukrotio more i neman Rahaba smrvio mudrošću."},{"v":13,"t":"Nebesa je svojim razbistrio dahom, a ruka mu je brzu zmiju probola."},{"v":14,"t":"Sve to samo djelić je djela njegovih, od kojih tek slabu jeku mi čujemo. Ali tko će shvatit' grom njegove moći?”"}]},"27":{"hr":[{"v":1,"t":"Job nastavi svoju besjedu i reče:"},{"v":2,"t":"“Živoga mi Boga što mi pravdu krati i Svesilnog koji dušu mi zagorča:"},{"v":3,"t":"sve dok duha moga bude još u meni, dok mi dah Božji u nosnicama bude,"},{"v":4,"t":"usne moje neće izustiti zloću niti će laž kakva doći na moj jezik."},{"v":5,"t":"Daleko od mene da vam dadem pravo, nedužnost svoju do zadnjeg daha branim."},{"v":6,"t":"Pravde svoje ja se držim, ne puštam je; zbog mojih me dana srce korit' neće."},{"v":7,"t":"Neka mi dušmana kob opakog snađe, a mog protivnika udes bezbožnikov!"},{"v":8,"t":"Čemu se nadati može kad vapije i kada uzdiže k Bogu dušu svoju?"},{"v":9,"t":"Hoće li čuti Bog njegove krikove kada se na njega obori nevolja?"},{"v":10,"t":"Zar će se radovat' on u Svesilnome, zar će Boga svakog časa zazivati?"},{"v":11,"t":"Ali Božju ruku ja ću vam pokazat' i neću vam sakrit namjere Svesilnog."},{"v":12,"t":"Eto, sve ste sami mogli to vidjeti, što se onda u ispraznosti gubite?”"},{"v":13,"t":"“Ovu sudbu Bog dosuđuje opakom, ovo baštini silnik od Svemogućeg."},{"v":14,"t":"Ima li sinova mnogo, mač ih čeka, a porod mu neće imat' dosta kruha."},{"v":15,"t":"Smrt će sahranit' preživjele njegove i udovice ih oplakivat neće."},{"v":16,"t":"Ako i srebra k'o praha nagomila, ako i nakupi haljina k'o blata,"},{"v":17,"t":"nek' ih skuplja, odjenut će ih pravednik, ljudi će nedužni podijeliti srebro."},{"v":18,"t":"Od paučine je kuću sagradio, kolibicu kakvu sebi diže čuvar:"},{"v":19,"t":"bogat je legao, al' po posljednji put; kad oči otvori, ničeg više nema."},{"v":20,"t":"Usred bijela dana strava ga spopada, noću ga oluja zgrabi i odnese."},{"v":21,"t":"Istočni ga vjetar digne i odvuče, daleko ga baca od njegova mjesta."},{"v":22,"t":"Bez milosti njime vitla on posvuda, dok mu ovaj kuša umaći iz ruke."},{"v":23,"t":"Rukama plješću nad njegovom propašću i zvižde na njega kamo god došao."}]},"28":{"hr":[{"v":1,"t":"“Da, srebro ima svoja nalazišta, a zlato mjesta gdje se pročišćava."},{"v":2,"t":"Ruda željezna iz zemlje se vadi, a iz rudače rastaljene bakar."},{"v":3,"t":"Ljudi tami postavljaju granice i kopaju do najvećih dubina za kamenom u mraku zakopanim."},{"v":4,"t":"Čeljad iz tuđine rovove dube do kojih ljudska ne dopire noga, visi njišuć' se, daleko od ljudi."},{"v":5,"t":"Krilo zemlje iz kojeg kruh nam niče kao od vatre sve je razrovano."},{"v":6,"t":"Stijene njene safira su skrovišta, prašina zlatna krije se u njima."},{"v":7,"t":"Tih putova ne znaju grabljivice, jastrebovo ih oko ne opaža."},{"v":8,"t":"Zvijeri divlje njima nisu kročile niti je kada lav njima prošao."},{"v":9,"t":"Ali na kamen diže čovjek ruku te iz korijena prevraća planine."},{"v":10,"t":"U kamenu prokopava prolaze, oko mu sve dragocjeno opaža."},{"v":11,"t":"Žilama vode on tok zaustavlja; stvari skrivene nosi na vidjelo."},{"v":12,"t":"Ali otkuda nam Mudrost dolazi? Na kojemu mjestu Razum prebiva?"},{"v":13,"t":"Čovjek njezina ne poznaje puta, u zemlji živih nisu je otkrili."},{"v":14,"t":"Bezdan govori: 'U meni je nema!' a more: 'Ne nalazi se kod mene!'"},{"v":15,"t":"Zlatom se čistim kupiti ne može, ni cijenu njenu srebrom odmjeriti;"},{"v":16,"t":"ne mjeri se ona zlatom ofirskim, ni oniksom skupim pa ni safirom."},{"v":17,"t":"Sa zlatom, staklom ne poređuje se, nit' se daje za sud od suha zlata."},{"v":18,"t":"Čemu spominjat' prozirac, koralje, bolje je steći Mudrost no biserje."},{"v":19,"t":"Što je prema njoj topaz etiopski? Ni čistim zlatom ne procjenjuje se."},{"v":20,"t":"Ali otkuda nam Mudrost dolazi? Na kojemu mjestu Razum prebiva?"},{"v":21,"t":"Sakrivena je očima svih živih; ona izmiče pticama nebeskim."},{"v":22,"t":"Propast paklena i Smrt izjavljuju: 'Za slavu njenu mi smo samo čuli.'"},{"v":23,"t":"Jedino je Bog put njen proniknuo, on jedini znade gdje se nalazi."},{"v":24,"t":"Jer pogledom granice zemlje hvata i opaža sve pod svodom nebeskim."},{"v":25,"t":"Kad htjede vjetru odredit težinu i mjerilom svu vodu izmjeriti,"},{"v":26,"t":"kad je zakone daždu nametnuo i oblacima gromovnim putove,"},{"v":27,"t":"tad ju je vidio te izmjerio, učvrstio i do dna ispitao."},{"v":28,"t":"A potom je rekao čovjeku: Strah Gospodnji - eto što je mudrost; 'Zla se kloni' - to ti je razumnost.”"}]},"29":{"hr":[{"v":1,"t":"Job nastavi svoju besjedu i reče:"},{"v":2,"t":"“O, da mi je prošle proživjet' mjesece, dane one kad je Bog nada mnom bdio,"},{"v":3,"t":"kad mi je nad glavom njegov sjao žižak a kroz mrak me svjetlo njegovo vodilo,"},{"v":4,"t":"kao u dane mojih zrelih jeseni kad s mojim stanom Bog prijateljevaše,"},{"v":5,"t":"kada uz mene još bijaše Svesilni i moji me okruživahu dječaci,"},{"v":6,"t":"kada mi se noge u mlijeku kupahu, a potokom ulja ključaše mi kamen!"},{"v":7,"t":"Kada sam na vrata gradska izlazio i svoju stolicu postavljao na trg,"},{"v":8,"t":"vidjevši me, sklanjali bi se mladići, starci bi ustavši stojeći ostali."},{"v":9,"t":"Razgovor bi prekidali uglednici i usta bi svoja rukom zatvarali."},{"v":10,"t":"Glavarima glas bi sasvim utihnuo, za nepce bi im se zalijepio jezik."},{"v":11,"t":"Tko god me slušao, blaženim me zvao, hvalilo me oko kad bi me vidjelo."},{"v":12,"t":"Jer, izbavljah bijednog kada je kukao i sirotu ostavljenu bez pomoći."},{"v":13,"t":"Na meni bješe blagoslov izgubljenih, srcu udovice ja veselje vraćah."},{"v":14,"t":"Pravdom se ja kao haljinom odjenuh, nepristranost bje mi plaštem i povezom."},{"v":15,"t":"Bjeh oči slijepcu i bjeh noge bogalju,"},{"v":16,"t":"otac ubogima, zastupnik strancima."},{"v":17,"t":"Kršio sam zube čovjeku opaku, plijen sam čupao iz njegovih čeljusti."},{"v":18,"t":"Govorah: 'U svom ću izdahnuti gnijezdu, k'o palma, bezbrojne proživjevši dane.'"},{"v":19,"t":"Korijenje se moje sve do vode pruža, na granama mojim odmara se rosa."},{"v":20,"t":"Pomlađivat će se svagda slava moja i luk će mi se obnavljati u ruci.'"},{"v":21,"t":"Slušali su željno što ću im kazati i šutjeli da od mene savjet čuju."},{"v":22,"t":"Na riječi mi ne bi ništa dometali i besjede su mi daždile po njima."},{"v":23,"t":"Za mnom žudjeli su oni k'o za kišom, otvarali usta k'o za pljuskom ljetnim."},{"v":24,"t":"Osmijeh moj bijaše njima ohrabrenje; pazili su na vedrinu moga lica."},{"v":25,"t":"Njima ja sam izabirao putove, kao poglavar ja sam ih predvodio, kao kralj među svojim kad je četama kao onaj koji tješi ojađene."}]},"30":{"hr":[{"v":1,"t":"“A sada, gle, podruguju se mnome ljudi po ljetima mlađi od mene kojih oce ne bih bio metnuo ni s ovčarskim psima stada svojega."},{"v":2,"t":"Ta što će mi jakost ruku njihovih kad im muževna ponestane snaga ispijena glađu i oskudicom."},{"v":3,"t":"Glodali su u pustinji korijenje i čestar opustjelih ruševina."},{"v":4,"t":"Lobodu su i s grmlja lišće brali, kao kruh jeli korijenje žukino."},{"v":5,"t":"Od društva ljudskog oni su prognani, za njima viču k'o za lopovima."},{"v":6,"t":"Živjeli su po strašnim jarugama, po spiljama i u raspuklinama."},{"v":7,"t":"Urlik im se iz šikarja dizao; po trnjacima ležahu stisnuti."},{"v":8,"t":"Sinovi bezvrijednih, soj bezimenih, bičevima su iz zemlje prognani."},{"v":9,"t":"Rugalicom sam postao takvima i njima sada služim kao priča!"},{"v":10,"t":"Gnušaju me se i bježe od mene, ne ustežu se pljunut' mi u lice."},{"v":11,"t":"I jer On luk mi slomi i satrije me, iz usta svojih izbaciše uzdu."},{"v":12,"t":"S desne moje strane rulja ustaje, noge moje u bijeg oni tjeraju, put propasti prema meni nasiplju."},{"v":13,"t":"Stazu mi ruše da bi me satrli, napadaju i ne brani im nitko,"},{"v":14,"t":"prolomom oni širokim naviru i kotrljaju se poput oluje."},{"v":15,"t":"Strahote sve se okreću na mene, mojeg ugleda kao vjetra nesta, poput oblaka iščeznu spasenje."},{"v":16,"t":"Duša se moja rasipa u meni, dani nevolje na me se srušili."},{"v":17,"t":"Noću probada bolest kosti moje, ne počivaju boli što me glođu."},{"v":18,"t":"Muka mi je i halju nagrdila i stegla me k'o ovratnik odjeće."},{"v":19,"t":"U blato me je oborila dolje, gle, postao sam k'o prah i pepeo."},{"v":20,"t":"K Tebi vičem, al' Ti ne odgovaraš; pred Tobom stojim, al' Ti i ne mariš."},{"v":21,"t":"Prema meni postao si okrutan; rukom preteškom na me se obaraš."},{"v":22,"t":"U vihor me dižeš, nosiš me njime, u vrtlogu me olujnom kovitlaš."},{"v":23,"t":"Da, znadem da si me smrti predao, saborištu zajedničkom svih živih."},{"v":24,"t":"Al' ne pruža li ruku utopljenik, ne viče li kad padne u nevolju?"},{"v":25,"t":"Ne zaplakah li nad nevoljnicima, ne sažalje mi duša siromaha?"},{"v":26,"t":"Sreći se nadah, a dođe nesreća; svjetlost čekah, a gle, zavi me tama."},{"v":27,"t":"Utroba vri u meni bez prestanka, svaki dan nove patnje mi donosi."},{"v":28,"t":"Smrknut idem, al' nitko me ne tješi; ustajem u zboru - da bih kriknuo."},{"v":29,"t":"Sa šakalima sam se zbratimio i nojevima postao sam drugom."},{"v":30,"t":"Na meni sva je koža pocrnjela, i kosti mi je sažgala ognjica."},{"v":31,"t":"Tužaljka mi je ugodila harfu, svirala mi glas narikača ima."}]},"31":{"hr":[{"v":1,"t":"Sa svojim očima savez sam sklopio da pogledat neću nijednu djevicu."},{"v":2,"t":"A što mi je Bog odozgo dosudio, kakva mi je baština od Svesilnoga?"},{"v":3,"t":"TÓa nije li nesreća za opakoga, a nevolja za one koji zlo čine?"},{"v":4,"t":"Ne proniče li on sve moje putove, ne prebraja li on sve moje korake?"},{"v":5,"t":"Zar sam ikad u društvu laži hodio, zar mi je noga k prijevari hitjela?"},{"v":6,"t":"Nek' me na ispravnoj mjeri Bog izmjeri pa će uvidjeti neporočnost moju!"},{"v":7,"t":"Ako mi je korak s puta kad zašao, ako mi se srce za okom povelo, ako mi je ljaga ruke okaljala,"},{"v":8,"t":"neka drugi jede što sam posijao, neka sve moje iskorijene izdanke!"},{"v":9,"t":"Ako mi zavede srce žena neka, ako za vratima svog bližnjeg kad vrebah,"},{"v":10,"t":"neka moja žena drugom mlin okreće, neka s drugim svoju podijeli postelju!"},{"v":11,"t":"Djelo bestidno time bih počinio, zločin kojem pravda treba da presudi,"},{"v":12,"t":"užego vatru što žeže do Propasti i što bi svu moju sažgala ljetinu."},{"v":13,"t":"Ako kada prezreh pravo sluge svoga il' služavke, sa mnom kad su se parbili,"},{"v":14,"t":"što ću učiniti kada Bog ustane? Što ću odvratit' kad račun zatraži?"},{"v":15,"t":"Zar nas oba on ne stvori u utrobi i jednako sazda u krilu majčinu?"},{"v":16,"t":"Ogluših li se na molbe siromaha ili rasplakah oči udovičine?"},{"v":17,"t":"Jesam li kada sam svoj jeo zalogaj a da ga nisam sa sirotom dijelio?"},{"v":18,"t":"TÓa od mladosti k'o otac sam mu bio, vodio sam ga od krila materina!"},{"v":19,"t":"Zar sam beskućnika vidio bez odjeće ili siromaha kog bez pokrivača"},{"v":20,"t":"a da mu bedra ne blagosloviše mene kad se runom mojih ovaca ogrija?"},{"v":21,"t":"Ako sam ruku na nevina podigao znajuć' da mi je na vratima branitelj,"},{"v":22,"t":"nek' se rame moje od pleća odvali i neka mi ruka od lakta otpadne!"},{"v":23,"t":"Jer strahote Božje na mene bi pale, njegovu ne bih odolio veličanstvu."},{"v":24,"t":"Zar sam u zlato pouzdanje stavio i rekao zlatu: 'Sigurnosti moja!'"},{"v":25,"t":"Zar sam se veliku blagu radovao, bogatstvima koja su mi stekle ruke?"},{"v":26,"t":"Zar se, gledajući sunce kako blista i kako mjesec sjajni nebom putuje,"},{"v":27,"t":"moje srce dalo potajno zavesti da bih rukom njima poljubac poslao?"},{"v":28,"t":"Grijeh bi to bio što za sudom vapije, jer Boga višnjega bih se odrekao."},{"v":29,"t":"Zar se obradovah nevolji dušmana i likovah kad ga je zlo zadesilo,"},{"v":30,"t":"ja koji ne dadoh griješiti jeziku, proklinjući ga i želeći da umre?"},{"v":31,"t":"Ne govorahu li ljudi mog šatora: 'TÓa koga nije on mesom nasitio'?"},{"v":32,"t":"Nikad nije stranac vani noćivao, putniku sam svoja otvarao vrata."},{"v":33,"t":"Zar sam grijehe svoje ljudima tajio, zar sam u grudima skrivao krivicu"},{"v":34,"t":"jer sam se plašio govorkanja mnoštva i strahovao od prezira plemenskog te sam mučao ne prelazeć' svoga praga?"},{"v":35,"t":"O, kad bi koga bilo da mene sasluša! Posljednju sam svoju riječ ja izrekao: na Svesilnom je sad da mi odgovori! Nek' mi optužnicu napiše protivnik,"},{"v":36,"t":"i ja ću je nosit' na svome ramenu, čelo ću njome k'o krunom uresit'."},{"v":37,"t":"Dat ću mu račun o svojim koracima i poput kneza pred njega ću stupiti.”"},{"v":38,"t":"Ako je na me zemlja moja vikala, ako su s njom brazde njezine plakale;"},{"v":39,"t":"ako sam plodove jeo ne plativši i ako sam joj ojadio ratare,"},{"v":40,"t":"[40a] neka mjesto žita po njoj niče korov, a mjesto ječma nek' posvud kukolj raste! [40b] Konac riječi Jobovih."}]},"32":{"hr":[{"v":1,"t":"Ona tri čovjeka prestadoše Jobu odgovarati, jer je on sebe smatrao nevinim."},{"v":2,"t":"Nato se rasrdi Elihu, sin Barakeelov, iz Buza, od plemena Ramova: planu gnjevom na Joba zato što je sebe držao pravednim pred Bogom;"},{"v":3,"t":"a planu gnjevom i na tri njegova prijatelja jer nisu više našli ništa što bi odgovorili te su tako Boga osudili."},{"v":4,"t":"Dok su oni govorili s Jobom, Elihu je šutio, jer su oni bili stariji od njega."},{"v":5,"t":"Ali kad vidje da ona tri čovjeka nisu više imala odgovora u ustima, planu od srdžbe."},{"v":6,"t":"I progovorivši, Elihu, sin Barakeelov, iz Buza, reče: “Po godinama svojim još mlad sam ja, a u duboku vi ste ušli starost; bojažljivo se zato ja ustezah znanje svoje pokazati pred vama."},{"v":7,"t":"Mišljah u sebi: 'Govorit će starost, mnoge godine pokazat će mudrost.'"},{"v":8,"t":"Uistinu, dah neki u ljudima, duh Svesilnog mudrim čini čovjeka."},{"v":9,"t":"Dob poodmakla ne daje mudrosti a niti starost pravednosti uči."},{"v":10,"t":"Zato vas molim, poslušajte mene da vam i ja znanje svoje izložim."},{"v":11,"t":"S pažnjom sam vaše besjede pratio i razloge sam vaše saslušao dok ste tražili što ćete kazati."},{"v":12,"t":"Na vama moja sva bijaše pažnja, al' ne bi nikog da Joba pobije ni da mu od vas tko riječ opovrgne."},{"v":13,"t":"Nemojte reći: 'Na mudrost smo naišli! Bog će ga pobit jer čovjek ne može.'"},{"v":14,"t":"Nije meni on besjedu upravio: odvratit mu neću vašim riječima."},{"v":15,"t":"Poraženi, otpovrgnut ne mogu, riječi zapeše u grlu njihovu."},{"v":16,"t":"Čekao sam! Al', gle, oni ne zbore. Umukoše, ni riječ više da kažu!"},{"v":17,"t":"Na meni je da progovorim sada, znanje ću svoje i ja izložiti."},{"v":18,"t":"Riječi mnoge u meni naviru dok iznutra moj duh mene nagoni."},{"v":19,"t":"Gle, nutrina mi je k'o mošt zatvoren, k'o nova će se raspući mješina."},{"v":20,"t":"Da mi odlane, govorit ću stoga, otvorit ću usne i odvratit' vama."},{"v":21,"t":"Nijednoj strani priklonit se neću niti laskat ja namjeravam kome."},{"v":22,"t":"Laskati ja ne umijem nikako, jer smjesta bi me Tvorac moj smaknuo."}]},"33":{"hr":[{"v":1,"t":"Čuj dakle, Jobe, što ću ti kazati, prikloni uho mojim besjedama."},{"v":2,"t":"Evo, usta sam svoja otvorio, a jezik riječi pod nepcem mi stvara."},{"v":3,"t":"Iskreno će ti zborit' srce moje, usne će čistu izreći istinu."},{"v":4,"t":"TÓa i mene je duh Božji stvorio, dah Svesilnoga oživio mene."},{"v":5,"t":"Ako uzmogneš, ti me opovrgni; spremi se da se suprotstaviš meni!"},{"v":6,"t":"Gle, kao i ti, i ja sam pred Bogom, kao i ti, od gline bjeh načinjen;"},{"v":7,"t":"zato ja strahom tebe motrit' neću, ruka te moja neće pritisnuti."},{"v":8,"t":"Dakle, na moje uši rekao si - posve sam jasno tvoje čuo riječi:"},{"v":9,"t":"'Nedužan sam i bez ikakva grijeha; prav sam i nema krivice na meni."},{"v":10,"t":"Al' On izlike protiv mene traži i za svojeg me drži dušmanina."},{"v":11,"t":"Noge je moje u klade metnuo, nad svakim mojim on pazi korakom.'"},{"v":12,"t":"Ovdje, kažem ti, u pravu ti nisi, jer s Bogom čovjek mjerit' se ne može."},{"v":13,"t":"Pa zašto s njime zamećeš prepirku što ti na svaku riječ ne odgovara?"},{"v":14,"t":"Bog zbori nama jednom i dva puta, al' čovjek na to pažnju ne obraća."},{"v":15,"t":"U snovima, u viđenjima noćnim, kada san dubok ovlada ljudima i na ležaju dok tvrdo snivaju,"},{"v":16,"t":"tad on govori na uho čovjeku i utvarama plaši ga jezivim"},{"v":17,"t":"da ga od djela njegovih odvrati, da u čovjeku obori oholost,"},{"v":18,"t":"da dušu njegovu spasi od jame i život mu od puta u Podzemlje."},{"v":19,"t":"Bolešću on ga kara na ležaju kad mu se kosti tresu bez prestanka,"},{"v":20,"t":"kad se kruh gadi njegovu životu i ponajbolje jelo duši njegovoj;"},{"v":21,"t":"kada mu tijelo gine naočigled i vide mu se kosti ogoljele,"},{"v":22,"t":"kad mu se duša približava jami a život njegov boravištu mrtvih."},{"v":23,"t":"Ako se uza nj nađe tad anđeo, posrednik jedan između tisuću, da čovjeka na dužnost opomene,"},{"v":24,"t":"pa se sažali nad njim i pomoli: 'Izbavi ga da u jamu ne ide; za život njegov nađoh otkupninu!"},{"v":25,"t":"Neka mu tijelo procvate mladošću, nek' se vrati u dane mladenačke!'"},{"v":26,"t":"Vapije k Bogu i Bog ga usliša: radosno On ga pogleda u lice; vrati čovjeku pravednost njegovu."},{"v":27,"t":"Tada čovjek pred ljudima zapjeva: 'Griješio sam i pravo izvrtao, ali mi Bog zlom nije uzvratio."},{"v":28,"t":"On mi je dušu spasio od jame i život mi se veseli svjetlosti.'"},{"v":29,"t":"Gle, sve to Bog je spreman učiniti do dva i do tri puta za čovjeka:"},{"v":30,"t":"da dušu njegovu spasi od jame i da mu život svjetlošću obasja."},{"v":31,"t":"Pazi dÓe, Jobe, dobro me poslušaj; šuti, jer nisam sve još izrekao."},{"v":32,"t":"Ako riječi još imaš, odvrati mi, zbori - rado bih opravdao tebe."},{"v":33,"t":"Ako li nemaš, poslušaj me samo: pazi, rad bih te poučit' mudrosti.”"}]},"34":{"hr":[{"v":1,"t":"Elihu nastavi svoju besjedu i reče:"},{"v":2,"t":"“I vi, mudraci, čujte što ću reći, vi, ljudi umni, poslušajte mene,"},{"v":3,"t":"jer uši nam prosuđuju besjede isto kao što nepce hranu kuša."},{"v":4,"t":"Zajedno ispitajmo što je pravo i razmislimo skupa što je dobro."},{"v":5,"t":"Job je utvrdio: 'Ja sam pravedan, ali Bog meni pravdu uskraćuje."},{"v":6,"t":"U pravu sam, a lašcem prave mene, nasmrt prostrijeljen, a bez krivnje svoje!'"},{"v":7,"t":"Zar gdje čovjeka ima poput Joba koji porugu pije kao vodu,"},{"v":8,"t":"sa zlikovcima koji skupa hodi i s opakima isti dijeli put?"},{"v":9,"t":"On tvrdi: 'Kakva korist je čovjeku od tog što Bogu ugoditi želi?'"},{"v":10,"t":"Stoga me čujte, vi ljudi pametni! Od Boga zlo je veoma daleko i nepravednost od Svemogućega,"},{"v":11,"t":"te on čovjeku plaća po djelima, daje svakom po njegovu vladanju."},{"v":12,"t":"Odista, Bog zla nikada ne čini, niti Svesilni kad izvrće pravo."},{"v":13,"t":"TÓa tko je njemu povjerio zemlju i vasioni svijet tko je stvorio?"},{"v":14,"t":"Kad bi on dah svoj u se povukao, kad bi čitav svoj duh k sebi vratio,"},{"v":15,"t":"sva bića bi odjednom izdahnula i u prah bi se pretvorio čovjek."},{"v":16,"t":"Ako razuma imaš, slušaj ovo, prikloni uho glasu riječi mojih."},{"v":17,"t":"Može li vladat' koji mrzi pravo? Najpravednijeg hoćeš li osudit'? -"},{"v":18,"t":"Onog koji kaže kralju: 'Nitkove!' a odličniku govori: 'Zlikovče!'"},{"v":19,"t":"Koji nije spram knezovima pristran i jednak mu je ubog i mogućnik, jer oni su djelo ruku njegovih?"},{"v":20,"t":"Zaglave za tren, usred gluhe noći: komešaju se narodi, prolaze; ni od čije ruke moćni padaju."},{"v":21,"t":"Jer, on nadzire pute čovjekove, pazi nad svakim njegovim korakom."},{"v":22,"t":"Nema toga mraka niti crne tmine gdje bi se mogli zlikovci sakriti."},{"v":23,"t":"Bog nikome unaprijed ne kaže kada će na sud pred njega stupiti."},{"v":24,"t":"Bez saslušanja on satire jake i stavlja druge na njihovo mjesto."},{"v":25,"t":"TÓa odveć dobro poznaje im djela! Sred noći on ih obara i gazi."},{"v":26,"t":"Ćuškom ih bije zbog zloće njihove na mjestu gdje ih svi vidjeti mogu."},{"v":27,"t":"Jer prestadoše za njime hoditi, zanemariše putove njegove"},{"v":28,"t":"goneć uboge da vape do njega i potlačene da k njemu leleču."},{"v":29,"t":"Al' miruje li, tko da njega gane? Zastre li lice, tko ga vidjet' može?"},{"v":30,"t":"Nad pucima bdi k'o i nad čovjekom da ne zavlada tko narod zavodi."},{"v":31,"t":"Kada bezbožnik Bogu svome kaže: 'Zavedoše me, više griješit neću."},{"v":32,"t":"Ne uviđam li, ti me sad pouči, i ako sam kad nepravdu činio, ubuduće ja činiti je neću!'"},{"v":33,"t":"Misliš da Bog mora njega kazniti, dok ti zamisli njegove prezireš? Al' kada ti odlučuješ, a ne ja, mudrost nam svoju istresi dÓe sada!"},{"v":34,"t":"Svi ljudi umni sa mnom će se složit' i svatko razuman koji čuje mene:"},{"v":35,"t":"Nepromišljeno Job je govorio, u riječima mu neima mudrosti."},{"v":36,"t":"Stoga, nek' se Job dokraja iskuša, jer odgovara poput zlikovaca;"},{"v":37,"t":"a svom grijehu još pobunu domeće, među nama on plješće dlanovima i hule svoje na Boga gomila.”"}]},"35":{"hr":[{"v":1,"t":"Elihu nastavi svoju besjedu i reče:"},{"v":2,"t":"“Zar ti misliš da pravo svoje braniš, da pravednost pred Bogom dokazuješ,"},{"v":3,"t":"kada mu kažeš: 'Što ti je to važno, i ako griješim, što ti činim time?'"},{"v":4,"t":"Na sve to ja ću odgovorit' tebi i prijateljima tvojim ujedno."},{"v":5,"t":"Po nebu se obazri i promatraj! Gledaj oblake: od tebe su viši!"},{"v":6,"t":"Ako griješiš, što si mu uradio, prijestupom svojim što si mu zadao?"},{"v":7,"t":"Ako si prav, što si dodao njemu i što iz ruke tvoje on dobiva?"},{"v":8,"t":"Opakost tvoja tebi slične pogađa i pravda tvoja čovjeku koristi."},{"v":9,"t":"Ali kad ispod teškog stenju jarma, kad vapiju na nasilje moćnika,"},{"v":10,"t":"nitko ne kaže: 'Gdje je Bog, moj tvorac, koji noć pjesmom veselom ispunja,"},{"v":11,"t":"umnijim nas od zvijeri zemskih čini i mudrijima od ptica nebeskih?'"},{"v":12,"t":"Tad vapiju, al' on ne odgovara poradi oholosti zlikovaca."},{"v":13,"t":"Ali kako je isprazno tvrditi da Bog njihove ne čuje vapaje, da pogled na njih ne svraća Svesilni!"},{"v":14,"t":"A kamoli tek kada ti govoriš: 'On ne vidi mene, parnica moja pred njime stoji, a ja na nj još čekam.'"},{"v":15,"t":"Ili: 'Njegova srdžba ne kažnjava, nimalo on za prijestupe ne mari.'"},{"v":16,"t":"Isprazno tada otvara Job usta i besjede gomila nerazumne.”"}]},"36":{"hr":[{"v":1,"t":"Elihu nastavi i reče:"},{"v":2,"t":"“Strpi se malo, pa ću te poučit', jer još nisam sve rekao za Boga."},{"v":3,"t":"Izdaleka ću svoje iznijet' znanje da Stvoritelja svojega opravdam."},{"v":4,"t":"Zaista, za laž ne znaju mi riječi, uza te je čovjek znanjem savršen."},{"v":5,"t":"Gle, Bog je silan, ali ne prezire, silan je snagom razuma svojega."},{"v":6,"t":"Opakome on živjeti ne daje, nevoljnicima pravicu pribavlja."},{"v":7,"t":"S pravednika on očiju ne skida, na prijestolje ih diže uz kraljeve da bi dovijeka bili uzvišeni."},{"v":8,"t":"Ako su negvam' oni okovani i užetima nevolje sputani,"},{"v":9,"t":"djela njihova on im napominje, kazuje im grijeh njine oholosti."},{"v":10,"t":"Tad im otvara uho k opomeni i poziva ih da se zla okane."},{"v":11,"t":"Poslušaju li te mu se pokore, dani im završavaju u sreći, u užicima godine njihove."},{"v":12,"t":"Ne slušaju li, od koplja umiru, zaglave, sami ne znajući kako."},{"v":13,"t":"A srca opaka mržnju njeguju, ne ištu pomoć kad ih on okuje;"},{"v":14,"t":"u cvatu svoga dječaštva umiru i venu poput hramskih milosnika."},{"v":15,"t":"Nevoljnog on bijedom njegovom spasava i u nesreći otvara mu oči:"},{"v":16,"t":"izbavit će te iz ždrijela tjeskobe k prostranstvima bezgraničnim izvesti, k prepunu stolu mesa pretiloga."},{"v":17,"t":"Ako sudio nisi opakima, ako si pravo krnjio siroti,"},{"v":18,"t":"nek' te obilje odsad ne zavede i nek' te dar prebogat ne iskvari."},{"v":19,"t":"Nek' ti je gavan k'o čovjek bez zlata, a čovjek jake ruke poput slaba."},{"v":20,"t":"Ne goni one koji su ti tuđi da rodbinu na njino mjesto staviš."},{"v":21,"t":"Pazi se da u nepravdu ne skreneš, jer zbog nje snađe tebe iskušenje."},{"v":22,"t":"Gle, uzvišen je Bog u svojoj snazi! Zar učitelja ima poput njega?"},{"v":23,"t":"Tko je njemu put njegov odredio? Tko će mu reći: 'Radio si krivo'?"},{"v":24,"t":"Spomeni se veličati mu djelo što ga pjesmama ljudi opjevaše."},{"v":25,"t":"S udivljenjem svijet čitav ga promatra, divi se čovjek, pa ma izdaleka."},{"v":26,"t":"Veći je Bog no što pojmit' možemo, nedokučiv je broj ljeta njegovih!"},{"v":27,"t":"U visini on skuplja kapi vode te dažd u paru i maglu pretvara."},{"v":28,"t":"Pljuskovi tada pljušte iz oblaka, po mnoštvu ljudskom dažde obilato."},{"v":29,"t":"Tko li će shvatit' širenje oblaka, tutnjavu strašnu njegovih šatora?"},{"v":30,"t":"Gle, on nad sobom razastire svjetlost i dno morsko on vodama pokriva."},{"v":31,"t":"Pomoću njih on podiže narode, u izobilju hranom ih dariva."},{"v":32,"t":"On munju drži objema rukama i kazuje joj kamo će zgoditi."},{"v":33,"t":"Glasom gromovnim sebe navješćuje, stiže s gnjevom da zgromi opačinu."}]},"37":{"hr":[{"v":1,"t":"Da, od toga i moje srce drhti i s mjesta svoga iskočiti hoće."},{"v":2,"t":"Čujte, čujte gromor glasa njegova, tutnjavu što mu iz usta izlazi."},{"v":3,"t":"Gle, munja lijeće preko cijelog neba - i sijevne blijesak s kraja na kraj zemlje -"},{"v":4,"t":"iza nje silan jedan glas se ori: to On gromori glasom veličajnim. Munje mu lete, nitko ih ne priječi, tek što mu je glas jednom odjeknuo."},{"v":5,"t":"Da, Bog gromori glasom veličajnim, djela velebna, neshvatljiva stvara."},{"v":6,"t":"Kad snijegu kaže: 'Zasniježi po zemlji!' i pljuskovima: 'Zapljuštite silno!'"},{"v":7,"t":"svakom čovjeku zapečati ruke da svi njegovo upoznaju djelo."},{"v":8,"t":"U brlog se tad zvijeri sve uvuku i na svojem se šćućure ležaju."},{"v":9,"t":"S južne se strane podiže oluja, a studen vjetri sjeverni donose."},{"v":10,"t":"Već led od daha Božjega nastaje i vodena se kruti površina."},{"v":11,"t":"I opet vodom puni on oblake, i sijevat' stanu oblaci munjama;"},{"v":12,"t":"kruže posvuda po volji njegovoj, što im naloži, to će izvršiti na licu cijelog kruga zemaljskoga."},{"v":13,"t":"Šalje ih - ili da kazni narode, ili da ih milosrđem obdari."},{"v":14,"t":"Poslušaj ovo, Jobe, umiri se i promotri djela Božja čudesna."},{"v":15,"t":"Znaš li kako Bog njima zapovijeda, kako munju iz oblaka svog pušta?"},{"v":16,"t":"Znaš li o čem vise gore oblaci? Čudesna to su znanja savršenog."},{"v":17,"t":"Kako ti gore od žege haljine u južnom vjetru kad zemlja obamre?"},{"v":18,"t":"Zar si nebesa s njim ti razapeo, čvrsta poput ogledala livenog?"},{"v":19,"t":"DÓe naputi me što da mu kažemo: zbog tmine se ne snalazimo više."},{"v":20,"t":"Zar ćeš mu reći: 'Hoću govoriti'? Ili na propast vlastitu pristati?"},{"v":21,"t":"Tko, dakle, može u svjetlost gledati na nebesima što se sja blistavo kada oblake rastjeraju vjetri?"},{"v":22,"t":"Sa sjevera k'o zlato je bljesnulo: veličanstvom strašnim Bog se odjenu!"},{"v":23,"t":"Da, Svesilnog doseći ne možemo, neizmjeran je u moći i sudu, velik u pravdi, nikog on ne tlači."},{"v":24,"t":"Zato ljudi svi neka ga se boje! Na mudrost oholu on i ne gleda!”"}]},"38":{"hr":[{"v":1,"t":"Nato Jahve odgovori Jobu iz oluje i reče:"},{"v":2,"t":"“Tko je taj koji riječima bezumnim zamračuje božanski promisao?"},{"v":3,"t":"Bokove svoje opaši k'o junak: ja ću te pitat', a ti me pouči."},{"v":4,"t":"Gdje si bio kad zemlju utemeljih? Kazuj, ako ti je znanje sigurno."},{"v":5,"t":"Znaš li tko joj je mjere odredio i nad njom uže mjerničko napeo?"},{"v":6,"t":"Na čemu joj počivaju temelji? Tko joj postavi kamen ugaoni"},{"v":7,"t":"dok su klicale zvijezde jutarnje i Božji uzvikivali dvorjani?"},{"v":8,"t":"Tko li zatvori more vratnicama kad je navrlo iz krila majčina;"},{"v":9,"t":"kad ga oblakom k'o haljom odjenuh i k'o pelenam' ovih maglom gustom;"},{"v":10,"t":"kad sam njegovu odredio među, vrata stavio sa prijevornicama?"},{"v":11,"t":"Dotle, ne dalje, rekao sam njemu, tu nek' se lomi ponos tvog valovlja!"},{"v":12,"t":"Zar si ikad zapovjedio jutru, zar si kazao zori mjesto njeno,"},{"v":13,"t":"da poduhvati zemlju za rubove i da iz nje sve bezbožnike strese;"},{"v":14,"t":"da je pretvori u glinu pečatnu i oboji je k'o kakvu haljinu."},{"v":15,"t":"Ona uzima svjetlost zlikovcima i pesnicu im lomi uzdignutu."},{"v":16,"t":"Zar si ti prodro do izvora morskih, po dnu bezdana zar si kad hodio?"},{"v":17,"t":"Zar su ti vrata smrti pokazali; vidje li dveri kraja mrtvih sjena?"},{"v":18,"t":"Zar si prostranstvo zemlje uočio? Govori, ako ti je znano sve to."},{"v":19,"t":"Koji putovi u dom svjetla vode, na kojem mjestu prebivaju tmine,"},{"v":20,"t":"da ih odvedeš u njine krajeve, da im put k stanu njihovu pokažeš?"},{"v":21,"t":"Ti znadeš to, tÓa davno ti se rodi, tvojih dana broj veoma je velik!"},{"v":22,"t":"Zar si stigao do riznica snijega i zar si tuče spremišta vidio"},{"v":23,"t":"što ih pričuvah za dane nevolje, za vrijeme boja krvava i rata?"},{"v":24,"t":"Kojim li se putem dijeli munja kada iskre po svoj zemlji prosipa?"},{"v":25,"t":"Tko li je jaz iskopao povodnju, tko prokrčio pute grmljavini"},{"v":26,"t":"da bi daždjelo na kraj nenastanjen, na pustinju gdje žive duše nema,"},{"v":27,"t":"da bi neplodnu napojio pustoš, da bi u stepi trava izniknula?"},{"v":28,"t":"Ima li kiša svoga roditelja? Tko je taj koji kapi rose rađa?"},{"v":29,"t":"Iz čijeg li mraz izlazi krila, tko slanu stvara što s nebesa pada?"},{"v":30,"t":"Kako čvrsnu vode poput kamena i led se hvata površja bezdana?"},{"v":31,"t":"Možeš li lancem vezati Vlašiće i razdriješiti spone Orionu,"},{"v":32,"t":"u pravo vrijeme izvesti Danicu, vodit' Medvjeda s njegovim mladima?"},{"v":33,"t":"Zar poznaješ ti zakone nebeske pa da njima moć na zemlji dodijeliš?"},{"v":34,"t":"Zar doviknuti možeš oblacima pa da pljuskovi tebe poslušaju?"},{"v":35,"t":"Zar na zapovijed tvoju munje lijeću i tebi zar se odazivlju: 'Evo nas'?"},{"v":36,"t":"Tko je mudrost darovao ibisu, tko li je pamet ulio u pijetla?"},{"v":37,"t":"Tko to mudro prebrojava oblake i tko nebeske izlijeva mjehove"},{"v":38,"t":"dok se zemlja u tijesto ne zgusne i dok se grude njezine ne slijepe?"},{"v":39,"t":"Zar ćeš ti plijen uloviti lavici ili ćeš glad utažit' lavićima"},{"v":40,"t":"na leglu svojem dok gladni čekaju i vrebaju na žrtvu iz zaklona?"},{"v":41,"t":"Tko hranu gavranovima pribavlja kad Bogu ptići njegovi cijuču i naokolo oblijeću bez hrane?"}]},"39":{"hr":[{"v":1,"t":"Znaš li kako se legu divokoze? Vidje li kako se mlade košute?"},{"v":2,"t":"Izbroji li koliko nose mjeseci, znaš li u koje doba se omlade?"},{"v":3,"t":"Sagnuvši se, polegu lanad svoju i breme usred pustinje odlažu,"},{"v":4,"t":"a kad im porod ojača, poraste, ostave ga i ne vraćaju mu se."},{"v":5,"t":"Tko dade divljem magarcu slobodu i tko to oglav skinu njemu s glave?"},{"v":6,"t":"U zavičaj mu dadoh ja pustinju i polja slana da ondje živuje."},{"v":7,"t":"Buci gradova on se podruguje i ne sluša goničevih povika."},{"v":8,"t":"Luta brdima, svojim pašnjacima, u potrazi za zeleni svakakvom."},{"v":9,"t":"Možeš li slugom učinit' bivola, zadržat' ga noć jednu za jaslama?"},{"v":10,"t":"Možeš li njega za brazdu prikovat' da ralo vuče po docima tvojim?"},{"v":11,"t":"Možeš li se osloniti na njega jer je njegova snaga prevelika i prepustit' mu težak svoj posao?"},{"v":12,"t":"Misliš li tebi da će se vratiti i na gumno ti dotjerati žito?"},{"v":13,"t":"Krilima svojim noj trepće radosno, iako krila oskudnih i perja."},{"v":14,"t":"On svoja jaja na zemlji ostavlja, povjerava ih pijesku da ih grije,"},{"v":15,"t":"ne mareć' što ih zgazit' može noga ili nekakva divlja zvijer zgnječiti."},{"v":16,"t":"S nojićima k'o s tuđima postupa; što mu je trud zaludu, on ne mari."},{"v":17,"t":"Jer Bog je njega lišio pameti, nije mu dao nikakva razbora."},{"v":18,"t":"Ali kada na let krila raširi, tada se ruga konju i konjaniku."},{"v":19,"t":"Zar si ti konja obdario snagom zar si mu ti vrat grivom ukrasio?"},{"v":20,"t":"Zar ti činiš da skače k'o skakavac, da u strah svakog nagoni hrzanjem?"},{"v":21,"t":"Kopitom zemlju veselo raskapa, neustrašivo srlja na oružje."},{"v":22,"t":"Strahu se ruga, ničeg se ne boji, ni pred mačem uzmaknuti neće."},{"v":23,"t":"Na sapima mu zvekeće tobolac, koplje sijeva i ubojna sulica."},{"v":24,"t":"Bijesan i nestrpljiv guta prostore; kad rog zasvira, tko će ga zadržat':"},{"v":25,"t":"na svaki zvuk roga on zarže: Ha! Izdaleka on ljuti boj već njuši, viku bojnu i poklič vojskovođa."},{"v":26,"t":"Zar po promislu tvojem lijeće soko i prema jugu krila svoja širi?"},{"v":27,"t":"Zar se na nalog tvoj diže orao i vrh timora gnijezdo sebi vije?"},{"v":28,"t":"Na litici on stanuje i noćÄi, na grebenima vrleti visokih."},{"v":29,"t":"Odatle na plijen netremice vreba, oči njegove vide nadaleko."},{"v":30,"t":"Krvlju se hrane njegovi orlići; gdje je ubijenih, tamo je i on.”"}]},"40":{"hr":[{"v":1,"t":"I Jahve se obrati Jobu i reče mu:"},{"v":2,"t":"“Zar će se s Jakim preti još kudilac? Tužitelj Božji nek' sam odgovori!”"},{"v":3,"t":"A Job odgovori Jahvi i reče:"},{"v":4,"t":"“Odveć sam malen: što da odgovorim? Rukom ću svoja zatisnuti usta."},{"v":5,"t":"Riječ rekoh - neću više započeti; rekoh dvije - al' neću nastaviti.”"},{"v":6,"t":"Nato Jahve odgovori Jobu iz oluje i reče:"},{"v":7,"t":"“Bokove svoje opaši k'o junak, ja ću te pitat', a ti me pouči."},{"v":8,"t":"Zar bi i moj sud pogaziti htio, okrivio me da sebe opravdaš?"},{"v":9,"t":"Zar ti mišica snagu Božju ima, zar glasom grmjet' možeš poput njega?"},{"v":10,"t":"Ogrni se sjajem i veličanstvom, dostojanstvom se odjeni i slavom."},{"v":11,"t":"Plani dÓe bijesom ognja jarosnoga, pogledom jednim snizi oholnika."},{"v":12,"t":"Ponositoga pogledaj, slomi ga, na mjestu satri svakoga zlikovca."},{"v":13,"t":"U zemlju sve njih zajedno zakopaj, u mračnu ih pozatvaraj tamnicu."},{"v":14,"t":"Tada ću i ja tebi odat' hvalu što si se svojom desnicom spasio."},{"v":15,"t":"A sada, dÓe promotri Behemota! Travom se hrani poput govečeta,"},{"v":16,"t":"u bedrima je, gle, snaga njegova, a krepkost mu u mišićju trbušnom."},{"v":17,"t":"Poput cedra rep podignut ukruti, sva su mu stegna ispreplele žile."},{"v":18,"t":"Mjedene cijevi kosti su njegove, zglobovi mu od željeza kvrge."},{"v":19,"t":"Prvenac on je Božjega stvaranja; mačem ga je naoružao tvorac."},{"v":20,"t":"Gore mu danak u hrani donose i sve zvijerje što po njima se igra."},{"v":21,"t":"Pod lotosom on zavaljen počiva, guštik močvarni i glib kriju ga."},{"v":22,"t":"Sjenu mu pravi lotosovo lišće, pod vrbama on hladuje potočnim."},{"v":23,"t":"Nabuja li rijeka, on ne strahuje: nimalo njega ne bi zabrinulo da mu u žvale i sav Jordan jurne."},{"v":24,"t":"Tko bi za oči uhvatio njega i tko bi mu nos sulicom probio?"},{"v":25,"t":"Zar loviš Levijatana udicom? Zar ćeš mu jezik zažvalit' užetom?"},{"v":26,"t":"Zar mu nozdrve trskom probost' možeš ili mu kukom probiti vilicu?"},{"v":27,"t":"Hoće li te on preklinjat' za milost, hoće li s tobom blago govoriti?"},{"v":28,"t":"I zar će s tobom savez on sklopiti da sveg života tebi sluga bude?"},{"v":29,"t":"Hoćeš li se s njim k'o s pticom poigrat' i vezat' ga da kćeri razveseliš?"},{"v":30,"t":"Hoće li se za nj cjenkati ribari, među sobom podijelit' ga trgovci?"},{"v":31,"t":"Možeš li kopljem njemu kožu izbost ili glavu mu probiti ostima?"},{"v":32,"t":"Podigni de ruku svoju na njega: za boj se spremi - bit će ti posljednji!"}]},"41":{"hr":[{"v":1,"t":"Zalud je nadu u njega gojiti, na pogled njegov čovjek već pogiba."},{"v":2,"t":"Junaka nema da njega razdraži, tko će mu se u lice suprotstavit'?"},{"v":3,"t":"Tko se sukobi s njim i živ ostade? Pod nebesima tog čovjeka nema!"},{"v":4,"t":"Prešutjet neću njegove udove, ni silnu snagu, ni ljepotu stasa."},{"v":5,"t":"Tko mu smije razodjenut' odjeću, tko li kroz dvostruk prodrijeti mu oklop?"},{"v":6,"t":"Tko će mu ralje rastvorit' dvokrilne kad strah vlada oko zubi njegovih?"},{"v":7,"t":"Hrbat mu je od ljuskavih štitova, zapečaćenih pečatom kamenim."},{"v":8,"t":"Jedni uz druge tako se sljubiše da među njima dah ne bi prošao."},{"v":9,"t":"Tako su čvrsto slijepljeni zajedno: priljubljeni, razdvojit' se ne mogu."},{"v":10,"t":"Kad kihne, svjetlost iz njega zapršti, poput zorinih vjeđa oči su mu."},{"v":11,"t":"Zublje plamsaju iz njegovih ralja, iskre ognjene iz njih se prosiplju."},{"v":12,"t":"Iz nozdrva mu sukljaju dimovi kao iz kotla što kipi na vatri."},{"v":13,"t":"Dah bi njegov zapalio ugljevlje, jer mu iz ralja plamenovi suču."},{"v":14,"t":"U šiji leži sva snaga njegova, a ispred njega užas se prostire."},{"v":15,"t":"Kad se ispravi, zastrepe valovi i prema morskoj uzmiču pučini."},{"v":16,"t":"Poput pećine srce mu je tvrdo, poput mlinskoga kamena otporno."},{"v":17,"t":"Pregibi tusta mesa srasli su mu, čvrsti su kao da su saliveni."},{"v":18,"t":"Zgodi li ga mač, od njeg se odbije, tako i koplje, sulica i strijela."},{"v":19,"t":"Poput slame je za njega željezo, mjed je k'o drvo iscrvotočeno."},{"v":20,"t":"On ne uzmiče od strelice s luka, stijenje iz praćke na nj k'o pljeva pada."},{"v":21,"t":"K'o slamčica je toljaga za njega, koplju se smije kad zazviždi nad njim."},{"v":22,"t":"Crepovlje oštro ima na trbuhu i blato njime ore k'o drljačom."},{"v":23,"t":"Pod njim vrtlog sav k'o lonac uskipi, uspjeni more k'o pomast u kotlu."},{"v":24,"t":"Za sobom svijetlu ostavlja on brazdu, regbi, bijelo runo bezdan prekriva."},{"v":25,"t":"Ništa slično na zemlji ne postoji i niti je tko tako neustrašiv."},{"v":26,"t":"I na najviše on s visoka gleda, kralj je svakome, i najponosnijim.”"}]},"42":{"hr":[{"v":1,"t":"A Job ovako odgovori Jahvi:"},{"v":2,"t":"“Ja znadem, moć je tvoja bezgranična: što god naumiš, to izvesti možeš."},{"v":3,"t":"Tko je taj koji riječima bezumnim zamračuje božanski promisao? Govorah stoga, ali ne razumjeh, o čudesima meni neshvatljivim."},{"v":4,"t":"O, poslušaj me, pusti me da zborim: ja ću te pitat', a ti me pouči."},{"v":5,"t":"Po čuvenju tek poznavah te dosad, ali sada te oči moje vidješe."},{"v":6,"t":"Sve riječi svoje zato ja poričem i kajem se u prahu i pepelu.”"},{"v":7,"t":"Kada Jahve izgovori Jobu ove riječi, reče on Elifazu Temancu: “Ti i tvoja dva prijatelja raspalili ste gnjev moj jer niste o meni onako pravo govorili kao moj sluga Job."},{"v":8,"t":"Zato uzmite sada sedam junaca i sedam ovnova i pođite k mome sluzi Jobu, pa prinesite za sebe paljenicu, a sluga moj Job molit će se za vas. Imat ću obzira prema njemu i neću vam učiniti ništa nažao zato što niste o meni onako pravo govorili kao moj sluga Job.”"},{"v":9,"t":"Tada odoše Elifaz iz Temana, Bildad iz Šuaha i Sofar iz Naamata i učiniše kako im je Jahve zapovjedio. I Jahve se obazre na Joba."},{"v":10,"t":"I Jahve vrati Joba u prijašnje stanje jer se založio za svoje prijatelje, pa mu još udvostruči ono što je posjedovao."},{"v":11,"t":"Tad se vratiše Jobu sva njegova braća, i sve njegove sestre, i svi prijašnji znanci te su jeli s njim kruh u njegovoj kući, žaleći ga i tješeći zbog svih nevolja što ih Jahve bijaše na nj poslao. Svaki mu darova po jedan srebrnik i po jedan zlatan prsten."},{"v":12,"t":"Jahve blagoslovi novo Jobovo stanje još više negoli prijašnje. Blago mu je brojilo četrnaest tisuća ovaca, šest tisuća deva, tisuću jarmova volova i tisuću magarica."},{"v":13,"t":"Imao je sedam sinova i tri kćeri."},{"v":14,"t":"Prvoj nadjenu ime Jemima, drugoj Kasija, a trećoj Keren-Hapuk."},{"v":15,"t":"U svem onom kraju ne bijaše žena tako lijepih kao Jobove kćeri. I otac im dade jednaku baštinu kao i njihovoj braći."},{"v":16,"t":"Poslije toga Job doživje dob od sto četrdeset godina i vidje djecu svoju i djecu svoje djece do četvrtog koljena. Potom umrije Job, star, nauživši se života."}]}},"PSA":{"1":{"hr":[{"v":1,"t":"Blago čovjeku koji ne slijedi savjeta opakih, ne staje na putu grešničkom i ne sjeda u zbor podrugljivaca,"},{"v":2,"t":"već uživa u Zakonu Jahvinu, o Zakonu njegovu misli dan i noć."},{"v":3,"t":"On je k'o stablo zasađeno pokraj voda tekućica što u svoje vrijeme plod donosi; lišće mu nikad ne vene, sve što radi dobrim urodi."},{"v":4,"t":"Nisu takvi opaki, ne, nisu takvi! Oni su k'o pljeva što je vjetar raznosi."},{"v":5,"t":"Stoga se opaki neće održati na sudu, ni grešnici u zajednici pravednih."},{"v":6,"t":"Jer Jahve zna put pravednih, a propast će put opakih."}]},"2":{"hr":[{"v":1,"t":"Zašto se bune narodi, zašto puci ludosti snuju?"},{"v":2,"t":"Ustaju kraljevi zemaljski, knezovi se rotÄe protiv Jahve i Pomazanika njegova:"},{"v":3,"t":"“Skršimo okove njihove i jaram njihov zbacimo!”"},{"v":4,"t":"Smije se onaj što na nebu stoluje, Gospod im se podruguje."},{"v":5,"t":"Tad im veli u svom gnjevu, žestinom ih on zbunjuje:"},{"v":6,"t":"“TÓa ja kralja svog postavih nad Sionom, svojom svetom gorom.”"},{"v":7,"t":"Obznanjujem odluku Jahvinu: Gospodin mi reče: “Ti si sin moj, danas te rodih."},{"v":8,"t":"Zatraži samo, i dat ću ti puke u baštinu, i u posjed krajeve zemaljske."},{"v":9,"t":"Vladat ćeš njima palicom gvozdenÄom i razbit ih kao sud lončarski.”"},{"v":10,"t":"Opametite se sada, vi kraljevi, Urazumite se, suci zemaljski."},{"v":11,"t":"Služite Jahvi sa strahom, s trepetom se pokorite njemu,"},{"v":12,"t":"da se ne razgnjevi te ne propadnete na putu, kad uskoro plane srdžba njegova. Blago svima koji se njemu utječu!"}]},"3":{"hr":[{"v":1,"t":"Psalam. Davidov. Kad je David bježao pred sinom Abšalomom."},{"v":2,"t":"Jahve, koliko je tlačitelja mojih, koliki se podižu na me!"},{"v":3,"t":"Mnogi su što o meni zbore: “Nema mu spasenja u Bogu!”"},{"v":4,"t":"Ti si ipak štit moj, Jahve; slavo moja, ti mi glavu podižeš."},{"v":5,"t":"Iza sveg glasa Jahvi zavapih, i on me usliša sa svete gore svoje."},{"v":6,"t":"Sad mogu leć' i usnuti, i onda ustat' jer me Jahve drži."},{"v":7,"t":"Ne bojim se tisuća ljudi što me opsjedaju dušmanski."},{"v":8,"t":"Ustani, o Jahve! Spasi me, o Bože moj! Ti udaraš po obrazu sve neprijatelje moje, opakima zube razbijaš."},{"v":9,"t":"U Jahve je spasenje: na tvom narodu tvoj je blagoslov!"}]},"4":{"hr":[{"v":1,"t":"Zborovođi. Uz žičana glazbala. Psalam. Davidov."},{"v":2,"t":"Kad zazovem, usliši me, Bože, pravdo moja, ti što me u tjeskobi izbavÄi: smiluj mi se, usliši moju molitvu!"},{"v":3,"t":"Sinovi čovječji, dokle će vam srca ostati tvrda? Zašto ispraznost ljubite, opsjenu slijedite?"},{"v":4,"t":"Znajte: Jahve čudesno uzvisuje prijatelja svoga; Gospodin će me uslišiti kad ga zazovem."},{"v":5,"t":"Promislite u srcima i ne griješite, dršćite na svojim ležajima i zanijemite."},{"v":6,"t":"Prinesite žrtve pravedne, u Jahvu se uzdajte!"},{"v":7,"t":"Mnogi govore: “Tko će nam pokazati sreću?” Obasjaj nas, Jahve, svjetlom svoga lica!"},{"v":8,"t":"Više si u srce moje ulio radosti nego kad obilno rode pšenica i vino."},{"v":9,"t":"Čim legnem, odmah u miru i usnem, jer mi samo ti, o Jahve, daješ miran počinak."}]},"5":{"hr":[{"v":1,"t":"Zborovođi. Uz frule. Psalam. Davidov."},{"v":2,"t":"Čuj, o Jahve, riječi moje, jecaje moje razaberi!"},{"v":3,"t":"Osvrni se na glas mog prizivanja, o Kralju moj i Bože moj, jer tebe vruće zazivam!"},{"v":4,"t":"Jahve, zorom glas mi već čuješ, zorom ti već lijem molitve u nadi čekajuć'."},{"v":5,"t":"Jer ti nisi Bog kom je nepravda mila: zlobniku nema boravka s tobom,"},{"v":6,"t":"opaki ne mogu opstati pred tvojim pogledom. Mrziš sve što čine bezakonje"},{"v":7,"t":"i uništavaš lažljivce. Varalica i krvopija Jahvi se gadi."},{"v":8,"t":"Po velikoj dobroti tvojoj unići ću u Dom tvoj; past ću ničice pred svetim Domom tvojim, Jahve, prepun poštovanja."},{"v":9,"t":"U svojoj me pravdi vodi poradi mojih dušmana, svoj put mi poravnaj pred očima."},{"v":10,"t":"U njihovim ustima iskrenosti nema, srce im je puno zloće; grlo im je grob otvoren, a jezikom laskaju."},{"v":11,"t":"Kazni ih, o Bože! Nek' propadnu oni i osnove njine, otjeraj ih zbog mnogih nedjela njihovih; tÓa oni se digoše na tebe."},{"v":12,"t":"Nek' se raduju svi što se utječu tebi, neka kliču sve dovijeka! Štiti ih i nek se vesele u tebi koji ljube ime tvoje,"},{"v":13,"t":"jer pravednika, Jahve, ti blagoslivljaš, dobrotom ga svojom k'o štitom zaklanjaš."}]},"6":{"hr":[{"v":1,"t":"Zborovođi. Uz žičano glazbalo. U oktavi. Psalam. Davidov."},{"v":2,"t":"Jahve, nemoj me karati u srdžbi svojoj, ne kažnjavaj me u svojoj jarosti!"},{"v":3,"t":"Smiluj mi se, Jahve, jer sam iznemog'o, Jahve, ozdravi me jer dršću kosti moje."},{"v":4,"t":"Duboko mi je duša potresena, a ti, o Jahve - dokle ćeš?"},{"v":5,"t":"Vrati se, Jahve, dušu mi izbavi, spasi me rad svoje dobrote:"},{"v":6,"t":"jer među mrtvima tko te se sjeća, u Podzemlju tko ti hvale pjeva?"},{"v":7,"t":"Iznemogoh od pusta jecanja, u noći postelju plačem zalijevam, suzama ležaj natapam."},{"v":8,"t":"Od žalosti oko mi gasne i slabi, jer su mnogi neprijatelji moji."},{"v":9,"t":"Odstupite od mene, svi opaki, jer je Jahve plač moj čuo."},{"v":10,"t":"Čuo je Jahve molbu moju, Jahve je primio moju molitvu."},{"v":11,"t":"Neka se postide i užasno zbune svi moji dušmani, i puni srama neka smjesta odstupe."}]},"7":{"hr":[{"v":1,"t":"Tužaljka. Davidova. Ispjeva je Jahvi zbog Kuša Benjaminovca."},{"v":2,"t":"O Jahve, Bože moj, tebi se utječem, od svih progonitelja spasi me, oslobodi,"},{"v":3,"t":"da mi dušu ne zgrabe kao lav što razdire, a nema tko da izbavi."},{"v":4,"t":"Jahve, Bože moj, ako to učinih, ako je nepravda na rukama mojim,"},{"v":5,"t":"ako zlom uzvratih prijatelju, ili oplijenih nepravedna tužitelja:"},{"v":6,"t":"neka mi dušmanin progoni dušu i zgrabi je, neka mi život u zemlju satre i jetru u prašinu baci."},{"v":7,"t":"Ustani, Jahve, u svom gnjevu, digni se na bijes tlačitelja mojih. Probudi se! Sud mi sazovi!"},{"v":8,"t":"Neka te okruži skupština narodna, nad njom sjedni visoko!"},{"v":9,"t":"O Jahve, dosudi mi pravo po pravosti mojoj i po nevinosti koja je u meni."},{"v":10,"t":"Dokrajči bezakonje zlotvora, pravedna podigni, pravedni Bože koji proničeš srca i bubrege."},{"v":11,"t":"Meni je štit Bog koji spasava čestita srca."},{"v":12,"t":"Bog je pravedan sudac, on povazdan prijeti:"},{"v":13,"t":"ako se ne obrate, mač će naoštriti, luk će svoj zapet' i pravo smjerit'."},{"v":14,"t":"Spremit će za njih smrtonosno oružje, strijele će svoje užariti."},{"v":15,"t":"Eto, zlotvor zače nepravdu, otrudnje pakošću i podlost rodi."},{"v":16,"t":"Iskopa jamu i prodube; sam u jamu svoju pade!"},{"v":17,"t":"Pakost će njegova pasti njemu na glavu, njemu na tjeme okrenut se nasilje njegovo."},{"v":18,"t":"A ja ću hvaliti Jahvu zbog pravde njegove i pjevat ću imenu Jahve višnjega."}]},"8":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Tijesci”. Psalam. Davidov."},{"v":2,"t":"Jahve, Gospode naš, divno je ime tvoje po svoj zemlji, veličanstvom nebo natkriljuješ!"},{"v":3,"t":"U ustima djece i dojenčadi hvalu si spremio protiv neprijatelja, da postidiš mrzitelja, zlotvora."},{"v":4,"t":"Gledam ti nebesa, djelo prstiju tvojih, mjesec i zvijezde što ih učvrsti -"},{"v":5,"t":"pa što je čovjek da ga se spominješ, sin čovječji te ga pohodiš?"},{"v":6,"t":"Ti ga učini malo manjim od Boga, slavom i sjajem njega okruni."},{"v":7,"t":"Vlast mu dade nad djelima ruku svojih, njemu pod noge sve podloži:"},{"v":8,"t":"ovce i svakolika goveda, i zvijeri poljske k tome,"},{"v":9,"t":"ptice nebeske i ribe morske, i što god prolazi stazama morskim."},{"v":10,"t":"Jahve, Gospode naš, divno je ime tvoje po svoj zemlji!"}]},"9":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Umri za sina”. Psalam. Davidov."},{"v":2,"t":"$ALEF Slavim te, Jahve, svim srcem svojim, ispovijedam sva čudesna djela tvoja."},{"v":3,"t":"Radujem se i kličem tebi, pjevam imenu tvome, Svevišnji!"},{"v":4,"t":"$BET Dušmani moji natrag krenuše, padoše i pred licem tvojim pogiboše."},{"v":5,"t":"Jer ti se zauze za moje pravo i parbu moju, ti sjede na prijesto - sudac pravedan:"},{"v":6,"t":"$GIMEL ti pokara pogane, pogubi bezbošca, ime im izbrisa dovijeka."},{"v":7,"t":"Dušmani klonuše, smrvljeni zauvijek, ti im gradove razori - nesta im spomena."},{"v":8,"t":"$HE Ali Jahve dovijeka stoluje, postavi prijesto svoj da sudi:"},{"v":9,"t":"sam po pravdi sudi krug zemaljski, izreče pucima osudu pravednu."},{"v":10,"t":"$VAU Jahve je tvrđava tlačenom, tvrđava spasa u danima tjeskobe."},{"v":11,"t":"Nek' se uzdaju u te koji znaju ime tvoje, jer ne ostavljaš onih što ljube tebe, o Jahve."},{"v":12,"t":"$ZAJIN Pjevajte Jahvi koji prebiva na Sionu, razglašujte među pucima djela njegova,"},{"v":13,"t":"jer ih se spomenu kao osvetnik krvi i siromaškog jauka ne zaboravi."},{"v":14,"t":"$HET Smiluj mi se, Jahve: pogledaj nevolju u koju me vrgoše neprijatelji moji, od vrata smrti izbavi me"},{"v":15,"t":"da naviještam sve hvale tvoje na vratima kćeri Sionske, da radostan kličem zbog spasenja tvoga."},{"v":16,"t":"$TET Pogani padoše u jamu koju sami iskopaše, zamka koju potajno staviše uhvati nogu njihovu."},{"v":17,"t":"Jahve se iskaza i sud održa; grešnik se spleo u djela svoja."},{"v":18,"t":"$JOD Nek' grešnici odu u Podzemlje, svi pogani što zaboraviše Boga."},{"v":19,"t":"$KAF Jer siromah neće pasti u zaborav zauvijek, ufanje ubogih neće biti zaludu dovijeka."},{"v":20,"t":"Ustani, Jahve, da se ne osili čovjek, nek' pogani budu osuđeni pred tobom!"},{"v":21,"t":"Strah im, o Jahve, utjeraj, nek' spoznaju pogani da su smrtnici!"}]},"10":{"hr":[{"v":1,"t":"$LAMED Zašto, Jahve, stojiš daleko, zašto se skrivaš u dane tjeskobe?"},{"v":2,"t":"Obijesni bezbožnik jadnika goni, u zamke ga hvata koje mu postavi."},{"v":3,"t":"Bezbožnik se pohlepom hvali, $NUN lakomac psuje i Jahvu prezire."},{"v":4,"t":"Bezbožnik zbori u obijesti svojoj: “Ne, istrage nema! TÓa ni Boga nema!” I u tome sva mu je misao."},{"v":5,"t":"Puti su mu svagda uspješni, na sudove tvoje on i ne misli, sve protivnike svoje prezire."},{"v":6,"t":"U srcu veli: “Neću posrnuti! Ni u kojem koljenu neću biti nesretan.”"},{"v":7,"t":"$PE Usta mu puna kletve, lukavstva i prijevare, pod jezikom njegovim muka i nesreća."},{"v":8,"t":"U zasjedi čuči pokraj ograda, potajno ubija nevina, $AJIN očima siromaha vreba."},{"v":9,"t":"U zaklonu sjedi k'o lav u pećini, vreba da opljačka jadnika i da ga povuče u mrežu."},{"v":10,"t":"Pritajen čuči na zemlji, od nasilja mu siromasi padaju."},{"v":11,"t":"U srcu svome veli: “ZÓaboravi Gospod, odvrati lice i nikoga ne vidi!”"},{"v":12,"t":"$KOF Ustani, Gospode Bože, podigni ruku, ne zaboravi siromaha."},{"v":13,"t":"Zašto da bezbožnik prezire Boga, zašto da kaže u srcu: “Neće kazniti!”"},{"v":14,"t":"$REŠ Jer ti vidiš, gledaš jad i nevolju, u ruci je mjeriš. Siromah se tebi predaje, ubogu ti si pomoć!"},{"v":15,"t":"$ŠIN Pakosnu grešniku satri mišicu, kazni mu pakost da je više ne bude!"},{"v":16,"t":"Jahve je kralj u vijeke vjekova, iz zemlje njegove nestat će pogana."},{"v":17,"t":"$TAU Počuj, o Jahve, čežnju siromašnih, okrijepi im srce, uho prikloni:"},{"v":18,"t":"da zaštitiš pravo ubogih i tlačenih, da straha više ne zadaje čovjek zemljanÄi."}]},"11":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov. Jahvi se utječem! Zašto dakle govorite duši mojoj: “Odleti u goru kao ptica!"},{"v":2,"t":"Gle, bezbožnici već luk napeše, za tetivu strijelu zapeše da iz potaje ustrijele pravednika."},{"v":3,"t":"Kad su temelji uzljuljani, što da učini pravednik?”"},{"v":4,"t":"Jahve je u svom svetom Hramu, na nebeskom sjedi prijestolju. Oči njegove motre, vjeđama proniče sinove ljudske."},{"v":5,"t":"Jahve proniče pravedna i nepravedna, iz dna duše mrzi silnika."},{"v":6,"t":"Na grešnike će izlit' žeravu i sumpor, vjetar ognjeni bit će dio njine sudbine."},{"v":7,"t":"Pravedan je Jahve i pravednost ljubi, čestiti će gledat' lice njegovo."}]},"12":{"hr":[{"v":1,"t":"Zborovođi. U oktavi. Psalam. Davidov."},{"v":2,"t":"U pomoć, Jahve, jer nestaje pobožnih, vjernosti nema više među ljudima!"},{"v":3,"t":"Svatko laže svome bližnjemu, govori usnama lažljivim i srcem dvoličnim."},{"v":4,"t":"Istrijebi, Jahve, sve usne lažljive i jezik hvastavi;"},{"v":5,"t":"one što zbore: “Jezik je naša snaga, naše su usne za nas: tko nam što može?”"},{"v":6,"t":"“Zbog nevolje tlačenih i jauka ubogih sada ću ustati - govori Jahve - spasenje donijet' onom tko ga želi.”"},{"v":7,"t":"Riječi su Jahvine riječi iskrene, srebro prokušano, od zemlje odvojeno, sedam puta očišćeno."},{"v":8,"t":"O Jahve, ti ćeš bdjeti nad nama, od naraštaja ovog čuvat' nas svagda,"},{"v":9,"t":"pa nek' se okolo vrzu zlotvori, nek' se izdižu ljudi najgori."}]},"13":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"TÓa dokle, Jahve, dokle ćeš me zaboravljati? Dokle ćeš skrivati lice od mene?"},{"v":3,"t":"Dokle ću nositi bol u duši; tugu u srcu obdan i obnoć? Dokle će se dušmanin dizat' na me?"},{"v":4,"t":"Pogledaj, usliši, Jahve, Bože moj! Prosvijetli mi oči da ne zaspim nasmrt,"},{"v":5,"t":"nek' ne kaže dušmanin: “Nadjačah njega!” Nek' ne kliču protivnici ako posrnem!"},{"v":6,"t":"Ja se u tvoju dobrotu uzdam, nek' mi se srce raduje spasenju tvome! Pjevat ću Jahvi koji mi učini dobro, pjevat ću imenu Jahve Svevišnjeg!"}]},"14":{"hr":[{"v":1,"t":"Zborovođi. Davidov. Bezumnik reče u srcu: “Nema Boga.” Pokvareni rade gadosti; nitko da čini dobro."},{"v":2,"t":"Jahve s nebesa gleda na sinove ljudske da vidi ima li tko razuman Boga da traži."},{"v":3,"t":"No, svi skrenuše zajedno, svi se pokvariše: nitko da čini dobro - nikoga nema."},{"v":4,"t":"Neće li se urazumiti svi što bezakonje čine, koji proždiru narod moj kao da jedu kruha? Ne zazivlju ime Jahvino:"},{"v":5,"t":"jednom će drhtati od straha, jer je Bog s rodom pravednim."},{"v":6,"t":"Želite razbiti nakane ubogog: Jahve je utočište njegovo."},{"v":7,"t":"O neka dođe sa Siona spas Izraelu! Kad Jahve promijeni udes naroda svoga, klicat će Jakov, radovat se Izrael."}]},"15":{"hr":[{"v":1,"t":"Psalam. Davidov. Jahve, tko smije prebivati u šatoru tvome, tko li stanovati na svetoj gori tvojoj?"},{"v":2,"t":"Onaj samo tko živi čestito, koji čini pravicu, i istinu iz srca zbori,"},{"v":3,"t":"i ne kleveće jezikom; koji bližnjem zla ne nanosi i ne sramoti susjeda svoga;"},{"v":4,"t":"koji zlikovca prezire, a poštuje one što se Jahve boje;"},{"v":5,"t":"koji se zaklinje prijatelju, a ne krši prisege, i ne daje novca na lihvu, i ne prima mita protiv nedužna. Tko tako čini, pokolebat' se neće dovijeka."}]},"16":{"hr":[{"v":1,"t":"Miktam. Davidov. Čuvaj me, Bože, jer se tebi utječem."},{"v":2,"t":"Jahvi rekoh: “Ti si moj gospodar, nema mi blaženstva bez tebe!”"},{"v":3,"t":"Za svetima što su u zemlji sav plamtim od čežnje!"},{"v":4,"t":"Gomilaju patnje moje koji slijede bogove tuđe. Ja im ljevanica nalijevat' neću, ime im spominjat' neću usnama."},{"v":5,"t":"Jahve mi je baština i kalež: Ti u ruci držiš moju sudbinu."},{"v":6,"t":"Na divnu zemlju padoše mi konopi, vrlo mi je mila moja baština."},{"v":7,"t":"Blagoslivljam Jahvu koji me svjetuje te me i noću srce opominje."},{"v":8,"t":"Jahve mi je svagda pred očima; jer mi je zdesna, neću posrnuti."},{"v":9,"t":"Stog' mi se raduje srce i kliče duša, i tijelo mi spokojno počiva."},{"v":10,"t":"Jer mi nećeš ostavit' dušu u Podzemlju ni dati da pravednik tvoj truleži ugleda."},{"v":11,"t":"Pokazat ćeš mi stazu u život, puninu radosti pred licem svojim, sebi zdesna blaženstvo vječno."}]},"17":{"hr":[{"v":1,"t":"Molitva. Davidova. Počuj, Jahve pravedni, i vapaj mi poslušaj, usliši molitvu iz usta iskrenih!"},{"v":2,"t":"Od tebe nek' mi dođe presuda, tvoje oči vide što je pravo."},{"v":3,"t":"Istraži mi srce, pohodi noću, ognjem me iskušaj, al' u meni nećeš nać' bezakonja. Ne zgriješiše usta moja"},{"v":4,"t":"kao što griješe ljudi: po riječima usta tvojih čuvah putove Zakona."},{"v":5,"t":"Korak mi čvrsto prionu za tvoje staze, ne zasta mi noga na putima tvojim."},{"v":6,"t":"Zazivam te, Bože, ti ćeš me uslišit': prikloni mi uho i čuj riječi moje."},{"v":7,"t":"Proslavi na meni dobrotu svoju, ti koji od dušmana izbavljaš one što se utječu desnici tvojoj."},{"v":8,"t":"Čuvaj me k'o zjenicu oka, sakrij me u sjenu krila svojih"},{"v":9,"t":"od zlotvora što na me nasrću. Dušmani me bijesni opkoljuju,"},{"v":10,"t":"bešćutno srce zatvaraju i ustima zbore naduto,"},{"v":11,"t":"Koraci njini sad me okružuju, smjeraju da me na zemlju obore;"},{"v":12,"t":"slični lavu dok se, zinuv, na plijen obara i laviću što vreba u potaji."},{"v":13,"t":"Ustani, Jahve, presretni ga i obori, od grešnika mi život mačem spasi,"},{"v":14,"t":"a rukom od ljudi, Gospodine: od ljudi kojih je dio ovaj život, kojima želudac puniš dobrima; kojih su sinovi siti, a djeci daju što im pretekne."},{"v":15,"t":"A ja ću u pravdi gledati lice tvoje, i jednom kad se probudim, sit ću ga se nagledati."}]},"18":{"hr":[{"v":1,"t":"Učitelju zbora. Od Jahvina sluge Davida koji Jahvi ispjeva ovu pjesmu u onaj dan kad ga Jahve oslobodi iz ruku neprijatelja"},{"v":2,"t":"Ljubim te, Jahve, kreposti moja!"},{"v":3,"t":"Jahve, hridino moja, utvrdo moja spase moj; Bože moj, pećino moja kojoj se utječem, štite moj, snago spasenja moga, tvrđavo moja!"},{"v":4,"t":"Zazvat ću Jahvu, hvale predostojna, i od dušmana bit ću izbavljen."},{"v":5,"t":"Valovi smrti okružiše mene, prestraviše me bujice pogubne."},{"v":6,"t":"Užad Podzemlja sputiše me, smrtonosne zamke padoše na me:"},{"v":7,"t":"u nevolji zazvah Jahvu i Bogu svome zavapih. Iz svog Hrama zov mi začu, i vapaj moj mu do ušiju doprije."},{"v":8,"t":"I zemlja se potrese i uzdrhta, uzdrmaše se temelji gora, pokrenuše se, jer On gnjevom planu."},{"v":9,"t":"Iz nosnica mu dim se diže, iz usta mu oganj liznu, ugljevlje živo od njega plamsa."},{"v":10,"t":"On nagnu nebesa i siđe, pod nogama oblaci mu mračni."},{"v":11,"t":"Na keruba stade i poletje; na krilima vjetra zaplovi."},{"v":12,"t":"Ogrnu se mrakom kao koprenom, prekri se tamnim vodama i oblacima tmastim,"},{"v":13,"t":"od blijeska pred licem njegovim užga se ugljevlje plameno."},{"v":14,"t":"Jahve s neba zagrmje, Svevišnjega glas se ori."},{"v":15,"t":"Odape strijele i dušmane rasu, izbaci munje i na zemlju ih obori."},{"v":16,"t":"Morska se dna pokazaše, i temelji svijeta postaše goli od strašne prijetnje Jahvine, od olujna daha gnjeva njegova."},{"v":17,"t":"On pruži s neba ruku i mene prihvati, iz silnih voda on me izbavi."},{"v":18,"t":"Od protivnika moćnog mene oslobodi, od dušmana mojih jačih od mene."},{"v":19,"t":"Navališe na me u dan zlosretni, ali me Jahve zaštiti,"},{"v":20,"t":"na polje prostrano izvede me, spasi me jer sam mu mio."},{"v":21,"t":"Po pravednosti mojoj Jahve mi uzvrati, po čistoći ruku mojih on me nagradi,"},{"v":22,"t":"jer čuvah putove Jahvine, od Boga se svoga ne udaljih."},{"v":23,"t":"Odredbe njegove sve su mi pred očima, zapovijedi njegove nisam odbacio,"},{"v":24,"t":"do srži odan njemu sam bio, čuvam se grijeha svakoga."},{"v":25,"t":"Jahve mi po pravdi mojoj vrati, čistoću ruku mojih vidje."},{"v":26,"t":"S prijateljem ti si prijatelj, poštenu poštenjem uzvraćaš."},{"v":27,"t":"S čovjekom čistim ti si čist, a lukavca izigravaš,"},{"v":28,"t":"jer narodu poniženu spasenje donosiš, a ponižavaš oči ohole."},{"v":29,"t":"Jahve, ti moju svjetiljku užižeš, Bože, tminu moju obasjavaš:"},{"v":30,"t":"s tobom udaram na čete dušmanske, s Bogom svojim preskačem zidine."},{"v":31,"t":"Savršeni su puti Gospodnji, i riječ je Božja ognjem kušana. On, samo on, štit je svima koji se k njemu utječu."},{"v":32,"t":"Jer tko je Bog osim Jahve? Tko li je hridina osim Boga našega?"},{"v":33,"t":"Taj Bog me snagom opasuje, stere mi put besprijekoran,"},{"v":34,"t":"noge mi dade brze k'o u košute i postavi me na visine čvrste,"},{"v":35,"t":"ruke mi za borbu uvježba i mišice da luk mjedeni napinju."},{"v":36,"t":"Daješ mi štit svoj koji spasava, tvoja me desnica drži, tvoja me brižljivost uzvisi."},{"v":37,"t":"Pouzdanje daješ mom koraku, i noge mi više ne posrću."},{"v":38,"t":"Pognah svoje dušmane i dostigoh, i ne vratih se dok ih ne uništih."},{"v":39,"t":"Obaram ih, ne mogu se dići, padaju, pod nogama mi leže."},{"v":40,"t":"Ti me opasa snagom za borbu, a protivnike moje meni podloži."},{"v":41,"t":"Ti dušmane moje u bijeg natjera, i rasprših one koji su me mrzili."},{"v":42,"t":"Vapiju u pomoć - nikog da pomogne; vapiju Jahvi - ne odaziva se."},{"v":43,"t":"Smrvih ih kao prah na vjetru, zgazih ih k'o blato na putu."},{"v":44,"t":"Ti me izbavi od bune u mom narodu, postavi me glavarom pogana, puk koji ne poznavah služi mi."},{"v":45,"t":"Svaki moj šapat pokorno on sluša, sinovi tuđinci meni laskaju;"},{"v":46,"t":"sinovi tuđinski gube srčanost, izlaze dršćuć' iz svojih utvrda."},{"v":47,"t":"Živio Jahve! Blagoslovljena hridina moja! Neka se uzvisi Bog, spasenje moje!"},{"v":48,"t":"Bog koji mi daje osvetu i narode meni pokorava."},{"v":49,"t":"Od dušmana me mojih izbavljaš i nad protivnike me moje izdižeš, ti mene od čovjeka silnika spasavaš."},{"v":50,"t":"Zato te slavim, Jahve, među pucima i psalam pjevam tvome Imenu:"},{"v":51,"t":"umnožio si pobjede kralju svojemu, pomazaniku svome milost si iskazao, Davidu i potomstvu njegovu navijeke."}]},"19":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"Nebesa slavu Božju kazuju, naviješta svod nebeski djelo ruku njegovih."},{"v":3,"t":"Dan danu to objavljuje, a noć noći glas predaje."},{"v":4,"t":"Nije to riječ, a ni govor nije, nije ni glas što se može čuti,"},{"v":5,"t":"al' po zemlji razliježe se jeka, riječi sve do nakraj svijeta sežu. Ondje suncu razape šator,"},{"v":6,"t":"te ono k'o ženik iz ložnice ide, k'o div kliče kad prelijeće stazu."},{"v":7,"t":"Izlazi ono od nebeskog kraja, i put mu se opet s krajem spaja, ne skriva se ništa žaru njegovu."},{"v":8,"t":"Savršen je Zakon Jahvin - dušu krijepi; pouzdano je Svjedočanstvo Jahvino - neuka uči;"},{"v":9,"t":"prÓava je naredba Jahvina - srce sladi; čista je zapovijed Jahvina - oči prosvjetljuje;"},{"v":10,"t":"neokaljan strah Jahvin - ostaje svagda; istiniti sudovi Jahvini - svi jednako pravedni,"},{"v":11,"t":"dragocjeniji od zlata, od zlata čistoga, slađi od meda, meda samotoka."},{"v":12,"t":"Sluga tvoj pomno na njih pazi, vrlo brižno on ih čuva."},{"v":13,"t":"Ali tko propuste svoje da zapazi? Od potajnih grijeha očisti me!"},{"v":14,"t":"Od oholosti čuvaj slugu svoga da mnome ne zavlada. Tad ću biti neokaljan, čist od grijeha velikoga."},{"v":15,"t":"Moje ti riječi omiljele i razmišljanje srca moga pred licem tvojim. Jahve, hridi moja, otkupitelju moj!"}]},"20":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"Uslišio te Jahve u dan nevolje, štitilo te ime Boga Jakovljeva!"},{"v":3,"t":"Poslao ti pomoć iz Svetišta, branio te sa Siona!"},{"v":4,"t":"Spomenuo se svih ti prinosnica, bila mu mila paljenica tvoja!"},{"v":5,"t":"Udijelio ti što ti srce želi, ispunio sve namisli tvoje!"},{"v":6,"t":"Radovali se tvojoj pobjedi, u ime Boga svoga dizali stjegove! Ispunio Jahve svaku molbu tvoju!"},{"v":7,"t":"Znam evo: Jahve će pobjedu dati svom pomazaniku, uslišit ga iz svetih nebesa snagom pobjedne desnice svoje."},{"v":8,"t":"Jedni se hvale kolima bojnim, drugi konjima, mi imenom Jahve, Boga našega!"},{"v":9,"t":"Oni posrću i padaju, mi se držimo i stojimo."},{"v":10,"t":"Jahve, daruj pobjedu kralju, usliši nas u dan kad te zazovemo!"}]},"21":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"Jahve, zbog tvoje se moći kralj veseli, zbog pomoći tvoje radosno kliče."},{"v":3,"t":"Ti mu ispuni želju srca, ne odbi molitve usana njegovih."},{"v":4,"t":"Ti ga predusrete blagoslovima sretnim, na glavu mu krunu stavi od suhoga zlata."},{"v":5,"t":"Za život te molio, i ti mu dade premnoge dane - za vijeke vjekova."},{"v":6,"t":"Pomoću tvojom slava je njegova velika, uresio si ga veličanstvom i sjajem."},{"v":7,"t":"Ti ga učini blagoslovom za vjekove, veseliš ga radošću lica svojega."},{"v":8,"t":"Doista, kralj se uzda u Jahvu i po dobroti Svevišnjega neće se pokolebati."},{"v":9,"t":"Tvoja ruka nek' pronađe sve dušmane tvoje, desnica tvoja neka stigne one koji te mrze!"},{"v":10,"t":"Nek' budu kao u peći ognjenoj kad se ukaže lice tvoje! Nek' ih Jahve gnjevom uništi, neka ih proguta oganj!"},{"v":11,"t":"Njihovo potomstvo satri sa zemlje i rod im iz sinova ljudskih."},{"v":12,"t":"Ako li stanu zlo kovati protiv tebe, ako spremaju spletke, neće uspjeti."},{"v":13,"t":"Ti ćeš ih natjerati u bijeg, svoj luk ćeš usmjeriti na njih."},{"v":14,"t":"Ustani, Jahve, u sili svojoj! Daj nam da pjesmama slavimo snagu tvoju!"}]},"22":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Košuta u zoru”. Psalam. Davidov."},{"v":2,"t":"Bože moj, Bože moj, zašto si me ostavio? Daleko si od ridanja moga."},{"v":3,"t":"Bože moj, vičem danju, al'ne odvraćaš; noću vapijem i nema mi počinka."},{"v":4,"t":"A ipak, ti u Svetištu prebivaš, Nado Izraelova!"},{"v":5,"t":"U tebe se očevi naši uzdaše, uzdaše se, i ti ih izbavi;"},{"v":6,"t":"k tebi su vikali i spasavali se, u tebe se uzdali, i postidjeli se nisu."},{"v":7,"t":"A ja, crv sam, a ne čovjek, ruglo ljudi i naroda prezir."},{"v":8,"t":"Koji me vode, podruguju se meni, razvlače usne, mašu glavom:"},{"v":9,"t":"“U Jahvu se on uzda, neka ga sad izbavi, neka ga spasi ako mu omilje!”"},{"v":10,"t":"Iz krila majčina ti si me izveo, mir mi dao na grudima majke."},{"v":11,"t":"Tebi sam predan iz materine utrobe, od krila majčina ti si Bog moj."},{"v":12,"t":"Ne udaljuj se od mene, blizu je nevolja, a nikog nema da mi pomogne."},{"v":13,"t":"Opkoliše me junci mnogobrojni, bašanski bikovi okružiše mene."},{"v":14,"t":"Ždrijela svoja razvaljuju na me k'o lav koji plijen kida i riče."},{"v":15,"t":"Kao voda razlih se, sve mi se kosti rasuše; srce mi posta poput voska, topi se u grudima mojim."},{"v":16,"t":"Grlo je moje kao crijep suho, i moj se jezik uz nepce slijepi: u prah smrtni bacio si mene."},{"v":17,"t":"Opkolio me čopor pasa, rulje me zločinačke okružile. Probodoše mi ruke i noge,"},{"v":18,"t":"sve kosti svoje prebrojiti mogu, a oni me gledaju i zure na me."},{"v":19,"t":"Haljine moje dijele među sobom i kocku bacaju za odjeću moju."},{"v":20,"t":"Ali ti, o Jahve, daleko mi ne budi; snago moja, pohiti mi u pomoć!"},{"v":21,"t":"Dušu moju istrgni maču, iz šapa pasjih život moj."},{"v":22,"t":"Spasi me iz ralja lavljih i jadnu mi dušu od rogova bivoljih!"},{"v":23,"t":"A sada, braći ću svojoj naviještat' ime tvoje, hvalit ću te usred zbora."},{"v":24,"t":"“Koji se bojite Jahve, hvalite njega! Svi od roda Jakovljeva, slavite njega! Svi potomci Izraelovi, njega se bojte!"},{"v":25,"t":"Jer nije prezreo ni zaboravio muku jadnika, i nije sakrio lice svoje od njega; kad ga je zazvao, on ga je čuo.”"},{"v":26,"t":"Zato ću te hvaliti u zboru veliku, pred vjernicima tvojim izvršit' zavjete."},{"v":27,"t":"Siromasi će jesti i nasitit će se, hvalit će Jahvu koji traže njega: nek' živi srce vaše dovijeka!"},{"v":28,"t":"Spomenut će se i Jahvi se vratit' svi krajevi zemlje; pred njim će n§icÄe pasti sve obitelji pogana."},{"v":29,"t":"Jer Jahvino je kraljevstvo, on je vladar pucima."},{"v":30,"t":"Njemu će se jedinom klanjati svi koji snivaju u zemlji, pred njim se sagnuti svi koji u prah silaze. I moja će duša za njega živjeti,"},{"v":31,"t":"njemu će služiti potomstvo moje. O Gospodu će se pripovijedat'"},{"v":32,"t":"slijedećem koljenu, o njegovoj pravdi naviještati narodu budućem: “Ovo učini Jahve!”"}]},"23":{"hr":[{"v":1,"t":"Psalam. Davidov. Jahve je pastir moj: ni u čem ja ne oskudijevam;"},{"v":2,"t":"na poljanama zelenim on mi daje odmora. Na vrutke me tihane vodi"},{"v":3,"t":"i krijepi dušu moju. Stazama pravim on me upravlja radi imena svojega."},{"v":4,"t":"Pa da mi je i dolinom smrti proći, zla se ne bojim, jer si ti sa mnom. Tvoj štap i palica tvoja utjeha su meni."},{"v":5,"t":"Trpezu preda mnom prostireš na oči dušmanima mojim. Uljem mi glavu mažeš, čaša se moja prelijeva."},{"v":6,"t":"Dobrota i milost pratit će mene sve dane života moga. U Jahvinu ću domu prebivati kroz dane mnoge."}]},"24":{"hr":[{"v":1,"t":"Psalam. Davidov. Jahvina je zemlja i sve na njoj, svijet i svi koji na njemu žive."},{"v":2,"t":"On ga na morima utemelji i na rijekama učvrsti."},{"v":3,"t":"Tko će uzići na Goru Jahvinu, tko će stajati na svetom mjestu njegovu?"},{"v":4,"t":"Onaj u koga su ruke čiste i srce nedužno: duša mu se ne predaje ispraznosti, i ne kune se varavo."},{"v":5,"t":"On blagoslov prima od Jahve i nagradu od Boga, Spasitelja svoga."},{"v":6,"t":"Takav je naraštaj onih koji traže njega, koji traže lice Boga Jakovljeva."},{"v":7,"t":"“Podignite, vrata, nadvratnike svoje, dižite se, dveri vječne, da uniđe Kralj slave!”"},{"v":8,"t":"“Tko je taj Kralj slave?” “Jahve silan i junačan, Jahve silan u boju!”"},{"v":9,"t":"“Podignite, vrata, nadvratnike svoje dižite se, dveri vječne, da uniđe Kralj slave!”"},{"v":10,"t":"“Tko je taj Kralj slave?” “Jahve nad Vojskama - on je Kralj slave!”"}]},"25":{"hr":[{"v":1,"t":"Davidov. $ALEF K tebi, Jahve, uzdižem dušu svoju,"},{"v":2,"t":"$BET u tebe se uzdam, Bože moj: ne daj da se postidim, da se ne vesele nada mnom dušmani!"},{"v":3,"t":"$GIMEL Koji se u tebe uzdaju, postidjet se neće: postidjet će se koji se lako iznevjere."},{"v":4,"t":"$DALET Pokaži mi, Jahve, svoje putove, nauči me svojim stazama!"},{"v":5,"t":"$HE Istinom me svojom vodi i pouči me, jer ti si Bog, moj Spasitelj: $VAU u tebe se pouzdajem svagda."},{"v":6,"t":"$ZAJIN Spomeni se, Jahve, svoje nježnosti i ljubavi svoje dovijeka."},{"v":7,"t":"$HET Ne spominji se grijeha moje mladosti ni prijestupa, spomeni me se po svojoj ljubavi - radi dobrote svoje, o Jahve!"},{"v":8,"t":"$TET Jahve je sama dobrota i pravednost: grešnike on na put privodi."},{"v":9,"t":"$JOD On ponizne u pravdi vodi i uči malene putu svome."},{"v":10,"t":"$KAF Sve su staze Jahvine istina i ljubav za onog koji čuva Savez njegov i propise."},{"v":11,"t":"$LAMED Jahve, radi svojeg imena grijeh moj mi oprosti, jer je velik."},{"v":12,"t":"$MEM Ima li koga da se boji Jahve? On će ga poučiti kojim će putem krenuti."},{"v":13,"t":"$NUN Duša će mu u sreći počivati, a potomci će njegovi zaposjesti zemlju."},{"v":14,"t":"$SAMEK Prisan je Jahve s onima koji ga se boje i Savez svoj objavljuje njima."},{"v":15,"t":"$AJIN K Jahvi su svagda oči moje upravljene, jer mi nogu izvlači iz zamke."},{"v":16,"t":"$PE Pogledaj na me i smiluj se meni, jer osamljen sam i nevoljan."},{"v":17,"t":"$SADE Odagnaj tjeskobe srca moga, iz bojazni mojih izbavi me!"},{"v":18,"t":"Vidi nevolju moju i muku i oprosti sve grijehe moje!"},{"v":19,"t":"$REŠ Pogledaj dušmane moje: kako ih je mnogo i kakvom me mržnjom žestokom mrze."},{"v":20,"t":"$ŠIN Čuvaj dušu moju, izbavi me: neću se postidjeti, jer se tebi utekoh."},{"v":21,"t":"$TAU Nedužnost i čestitost nek' me štite, jer u tebe se uzdam, o Jahve."},{"v":22,"t":"Izbavi, Bože, Izraela iz sviju tjeskoba njegovih."}]},"26":{"hr":[{"v":1,"t":"Davidov. Dosudi mi pravo, Jahve, jer hodih u nedužnosti, i uzdajuć' se u Jahvu ja se ne pokolebah."},{"v":2,"t":"Ispitaj me, Jahve, iskušaj me, istraži mi bubrege i srce."},{"v":3,"t":"Jer tvoja je dobrota pred očima mojim, u istini tvojoj ja hodim."},{"v":4,"t":"S ljudima opakim ja ne sjedim i ne svraćam podlima."},{"v":5,"t":"Mrsko mi je društvo zlotvora, i s bezbošcima sjesti ne želim."},{"v":6,"t":"U nedužnosti ruke svoje perem i obilazim žrtvenik tvoj, Jahve,"},{"v":7,"t":"da tvoju hvalu javno razglasim i pripovijedam sva divna djela tvoja."},{"v":8,"t":"O Jahve, ljubim dom u kojem prebivaš i mjesto gdje slava tvoja stoluje."},{"v":9,"t":"Ne pogubi mi dušu s grešnicima ni život moj s krvolocima;"},{"v":10,"t":"na rukama je njihovim zločin, a desnica im puna mita."},{"v":11,"t":"A ja u nedužnosti svojoj hodim: izbavi me, milostiv mi budi."},{"v":12,"t":"Noga mi stoji na pravu putu: u zborovima blagoslivljat ću Jahvu."}]},"27":{"hr":[{"v":1,"t":"Davidov. Jahve mi je svjetlost i spasenje: koga da se bojim? Jahve je štit života moga: pred kime da strepim?"},{"v":2,"t":"Kad navale na me zlotvori da mi tijelo žderu, protivnici moji i dušmani, oni posrću i padaju."},{"v":3,"t":"Nek' se vojska protiv mene utabori, srce se moje ne boji; nek' i rat plane protiv mene, i tada pun sam pouzdanja."},{"v":4,"t":"Za jedno molim Jahvu, samo to ja tražim: da živim u Domu Jahvinu sve dane života svoga, da uživam milinu Jahvinu i Dom njegov gledam."},{"v":5,"t":"U sjenici svojoj on me zaklanja u dan kobni; skriva me u skrovištu Šatora svoga, na hridinu on me uzdiže."},{"v":6,"t":"I sada izdižem glavu iznad dušmana oko sebe. U njegovu ću Šatoru prinositi žrtve radosne, Jahvi ću pjevat' i klicati."},{"v":7,"t":"Slušaj, o Jahve, glas moga vapaja, milostiv mi budi, usliši me!"},{"v":8,"t":"Moje mi srce govori: “Traži lice njegovo!” Da, lice tvoje, o Jahve, ja tražim."},{"v":9,"t":"Ne skrivaj lica svoga od mene. Ne odbij u gnjevu slugu svoga! Ti, Pomoći moja, nemoj me odbaciti! I ne ostavi me, Bože, Spasitelju moj!"},{"v":10,"t":"Ako me otac i mati ostave, Jahve će me primiti."},{"v":11,"t":"Nauči me, Jahve, putu svojemu, ravnom me stazom povedi poradi protivnika mojih."},{"v":12,"t":"Bijesu dušmana mojih ne predaj me, jer ustadoše na mene svjedoci lažni koji dašću nasiljem."},{"v":13,"t":"Vjerujem da ću uživati dobra Jahvina u zemlji živih."},{"v":14,"t":"U Jahvu se uzdaj, ojunači se, čvrsto nek' bude srce tvoje: u Jahvu se uzdaj!"}]},"28":{"hr":[{"v":1,"t":"Davidov. K tebi, o Jahve, vapijem, hridino moja, ne ogluši se na me: da neuslišan ne postanem kao oni koji u grob silaze."},{"v":2,"t":"Čuj moje zazivanje dok tebi vapijem, dok ruke uzdižem svetomu Hramu tvojem."},{"v":3,"t":"Ne uzmi me s bezbožnicima i s onima koji čine bezakonje, koji govore slatko s bližnjima a u srcu im je pakost."},{"v":4,"t":"Daj im po djelima njihovim i po zloći njihovih nedjela! Po djelu ruku njihovih plati im, uzvrati im po njihovoj zasluzi!"},{"v":5,"t":"Jer ne mare za čine Jahvine ni za djelo ruku njegovih: nek' ih obori i više ne podigne!"},{"v":6,"t":"Blagoslovljen Jahve što usliša zazivanje moje! Jahve mi je zaklon, on štit je moj."},{"v":7,"t":"U njega se srce moje pouzdalo i pomoć mi dođe; zato mi kliče srce i pjesmom njega slavim."},{"v":8,"t":"Jahve je jakost narodu svome, tvrđava spasa svom pomazaniku."},{"v":9,"t":"Spasi narod svoj i blagoslovi svoju baštinu, pasi ih i nosi ih dovijeka!"}]},"29":{"hr":[{"v":1,"t":"Psalam. Davidov. Prinesite Jahvi, o sinovi Božji, prinesite Jahvi slavu i moć!"},{"v":2,"t":"Prinesite Jahvi slavu njegova imena, poklonite se Jahvi u svetištu njegovu!"},{"v":3,"t":"Čuj! Jahve nad vodama, Jahve nad vodama silnim!"},{"v":4,"t":"Čuj! Jahve u sili, Jahve u veličanstvu!"},{"v":5,"t":"Čuj! Jahve lomi cedre, Jahve lomi cedre libanske,"},{"v":6,"t":"i Liban skakuće poput teleta, a Sirion kao mlado bivolče!"},{"v":7,"t":"Čuj! Jahve sipa munje, Jahve sipa munje ognjene!"},{"v":8,"t":"Čuj! Jahve potresa pustinjom, Jahve potresa pustinjom kadeškom!"},{"v":9,"t":"Čuj! Od straha se mladÄe košute, prerano se mladÄe košute šumske. [3b] Čuj! Bog veličanstveni zagrmje, [9a] a u Hramu njegovu svi kliknuše: Slava!"},{"v":10,"t":"Jahve nad valima stoluje, stoluje Jahve - kralj dovijeka!"},{"v":11,"t":"Jahve narodu svom daje jakost, Jahve narod svoj mirom blagoslivlje."}]},"30":{"hr":[{"v":1,"t":"Psalam. Pjesma za posvećenje Doma. Davidov."},{"v":2,"t":"Veličam te, Jahve, jer si me izbavio i nisi dao da se raduju nada mnom dušmani."},{"v":3,"t":"Jahve, Bože moj, zazvah te, i ti si me ozdravio;"},{"v":4,"t":"Jahve, izveo si mi dušu iz Podzemlja, na rubu groba ti si me oživio."},{"v":5,"t":"Pjevajte Jahvi, vjernici njegovi, zahvaljujte svetom imenu njegovu!"},{"v":6,"t":"Jer samo za tren traje srdžba njegova, a čitav život dobrota njegova. Večer donese suze, a jutro klicanje."},{"v":7,"t":"U svojoj sreći rekoh: “Neću se pokolebati nikada!”"},{"v":8,"t":"Dobrotom si me, o Jahve, na goru nade postavio, ali čim lice sakriješ, sav se uplašim."},{"v":9,"t":"Tada, Jahve, zavapih k tebi i zazvah milosrđe Boga svojega:"},{"v":10,"t":"“Kakva je korist od krvi moje, kakva korist da u grob siđem? Zar će te prašina slaviti, zar će naviještati vjernost tvoju?”"},{"v":11,"t":"Slušaj, o Jahve, i smiluj se meni; Jahve, budi mi na pomoć!"},{"v":12,"t":"Okrenuo si moj plač u igranje, skinuo kostrijet s mene i opasao me radošću."},{"v":13,"t":"Zato ti pjeva duša moja i neće zamuknuti: Jahve, Bože moj, dovijeka ću te hvaliti!"}]},"31":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"Tebi se, Jahve, utječem, o, da se ne postidim nikada: u svojoj me pravdi izbavi!"},{"v":3,"t":"Prikloni k meni uho svoje, pohiti da me oslobodiš! Budi mi hrid zaštite, tvrđava spasenja."},{"v":4,"t":"Jer ti si hrid moja, tvđava moja, radi svoga imena vodi me i ravnaj."},{"v":5,"t":"Izvuci me iz mreže koju mi zapeše, jer ti si moje utočište."},{"v":6,"t":"U tvoje ruke duh svoj predajem: otkupi me, Jahve, Bože vjerni."},{"v":7,"t":"Ti mrziš one koji štuju ništavne kumire, a ja se u Jahvu uzdam."},{"v":8,"t":"Radosno ću klicat' tvojoj milosti, jer si na moju bijedu pogledao, pomogao u tjeskobi duši mojoj."},{"v":9,"t":"Nisi me predao u ruke dušmana, noge si mi na prostran put izveo."},{"v":10,"t":"Smiluj mi se, Jahve, jer sam u tjeskobi, od jada slabi mi oko, duša i tijelo."},{"v":11,"t":"Život mi se troši u gorčini, ljeta moja u jecanju. U muci mi se iscrpila snaga i kosti su moje klonule."},{"v":12,"t":"Dušmanima svojim postao sam ruglo, susjedima podsmijeh, a znancima strašilo; koji me vide vani, bježe od mene."},{"v":13,"t":"Nestalo me k'o mrtvaca iz sjećanja ljudi, postadoh k'o razbijena posuda."},{"v":14,"t":"Čujem šaputanje mnogih, užas odasvud: sastaju se protiv mene i smišljaju kako da mi život oduzmu."},{"v":15,"t":"A ja se, Jahve, u tebe uzdam; govorim: Ti si Bog moj!"},{"v":16,"t":"U tvojoj je ruci sudbina moja: istrgni me iz ruke dušmana i onih koji me progone!"},{"v":17,"t":"Rasvijetli lice nad slugom svojim, po svojoj me dobroti spasi."},{"v":18,"t":"Jahve, ne bilo me stid što tebe zazvah! Neka se postide zlotvori, nek' u Podzemlju zamuknu."},{"v":19,"t":"Nek' zanijeme usne lažljive koje protiv pravednika govore drsko, oholo i prezirno."},{"v":20,"t":"O, kako je velika, Jahve, tvoja dobrota, koju čuvaš za one koji te se boje, koju iskazuješ onima što se tebi utječu naočigled sinovima čovječjim."},{"v":21,"t":"Zaklanjaš ih štitom lica svoga od zavjera ljudskih; u šatoru svom ih skrivaš od jezika svadljivih."},{"v":22,"t":"Blagoslovljen Jahve jer me obasu čudesnom dobrotom u gradu tvrdom."},{"v":23,"t":"U tjeskobi svojoj već mišljah: “Odbačen sam od pogleda tvoga.” Ali ti si čuo glas mog zaziva dok sam tebi vapio."},{"v":24,"t":"Ljubite Jahvu, svi sveti njegovi: čuva Jahve svoje vjernike, a po zasluzi vraća onima koji postupaju oholo."},{"v":25,"t":"Budite hrabri i jaka srca, svi koji se u Jahvu uzdate!"}]},"32":{"hr":[{"v":1,"t":"Davidov. Poučna pjesma. Blažen onaj kome je grijeh otpušten, kome je zločin pokriven!"},{"v":2,"t":"Blago čovjeku kome Jahve ne ubraja krivnju i u čijemu duhu nema prijevare!"},{"v":3,"t":"Prešutjet' sam htio, al' kosti mi klonuše od neprestana jecanja."},{"v":4,"t":"Danju i noću ruka me tvoja tištala, snaga mi se trošila k'o za ljetnih žega."},{"v":5,"t":"Tad grijeh svoj tebi priznah i krivnju svoju više ne skrivah. Rekoh: “Priznat ću Jahvi prijestup svoj”, i ti si mi krivnju grijeha oprostio."},{"v":6,"t":"Zato nek' ti se moli pobožnik svaki u času nevolje. Kad bujice silne navale, njega neće stići."},{"v":7,"t":"Utočište ti si moje, od tjeskobe ti ćeš me sačuvat', odjenut' me radošću spasenja."},{"v":8,"t":"Učit ću te, put ti kazat' kojim ti je ići, svjetovat ću te, oko će moje bdjeti nad tobom."},{"v":9,"t":"Ne budite kao konj ili mazga bez razuma: divljinu im krotiš vođicama i uzdom, inače im se ne primiči!"},{"v":10,"t":"Bezbožnika taru mnoge nevolje, a tko se uzda u Jahvu, njega okružuje milost."},{"v":11,"t":"Radujte se Jahvi i kličite, pravedni, kličite svi koji ste srca čestita!"}]},"33":{"hr":[{"v":1,"t":"Pravednici, Jahvi kličite! Hvaliti ga pristoji se čestitima."},{"v":2,"t":"Slavite Jahvu na harfi, na liri od deset žica veličajte njega!"},{"v":3,"t":"Pjesmu novu zapjevajte njemu i glazbala skladna popratite poklicima."},{"v":4,"t":"Jer prÓava je riječ Jahvina i vjernost su sva djela njegova."},{"v":5,"t":"On ljubi pravdu i pravo: puna je zemlja dobrote Jahvine."},{"v":6,"t":"Jahvinom su riječju nebesa sazdana i dahom usta njegovih sva vojska njihova."},{"v":7,"t":"Vodu morsku on sabire kao u mješinu i bezdane stavlja u spremišta."},{"v":8,"t":"Zemlja sva neka pred Jahvom strepi, neka ga se boje svi stanovnici svijeta!"},{"v":9,"t":"Jer on reče - i sve postade, naredi - i sve se stvori."},{"v":10,"t":"Jahve razbija nakane pucima, mrsi namjere narodima."},{"v":11,"t":"Naum Jahvin dovijeka ostaje i misli srca njegova od koljena do koljena."},{"v":12,"t":"Blago narodu kojemu je Jahve Bog, Narodu koji on odabra sebi za baštinu!"},{"v":13,"t":"Gospodin motri s nebesa i gleda sve sinove čovječje."},{"v":14,"t":"Iz svoga prebivališta motri sve stanovnike zemaljske:"},{"v":15,"t":"on je svima srca stvorio i pazi na sva djela njihova."},{"v":16,"t":"Ne spasava kralja vojska mnogobrojna, ne spasava velika sila junaka."},{"v":17,"t":"Isprazno se od konja nadati spasenju, jačina njegova ne izbavlja."},{"v":18,"t":"Oko je Jahvino nad onima koji ga se boje, nad onima koji se uzdaju u milost njegovu:"},{"v":19,"t":"da im od smrti život spasi, da ih hrani u danima gladi."},{"v":20,"t":"Naša se duša Jahvi nada, on je pomoć i zaštita naša."},{"v":21,"t":"Srce nam se u njemu raduje, u njegovo sveto ime mi se uzdamo."},{"v":22,"t":"Neka dobrota tvoja, o Jahve, bude nad nama, kao što se mi u tebe uzdamo!"}]},"34":{"hr":[{"v":1,"t":"Davidov. Kada se David pravio ludim pred Abimelekom, a on"},{"v":2,"t":"$ALEF Blagoslivljat ću Jahvu u svako doba, njegova će mi hvala biti svagda na ustima!"},{"v":3,"t":"$BET Nek' se Jahvom duša moja hvali: nek' čuju ponizni i nek' se raduju!"},{"v":4,"t":"$GIMEL Veličajte sa mnom Jahvu, uzvisujmo ime njegovo zajedno!"},{"v":5,"t":"$DALETTražio sam Jahvu, i on me usliša, izbavi me od straha svakoga."},{"v":6,"t":"$HE U njega gledajte i razveselite se, da se ne postide lica vaša."},{"v":7,"t":"$ZAJIN Eto, jadnik vapi, a Jahve ga čuje, izbavlja ga iz svih tjeskoba."},{"v":8,"t":"$HET Anđeo Jahvin tabor podiže oko njegovih štovalaca da ih spasi."},{"v":9,"t":"$TET Kušajte i vidite kako dobar je Jahve: blago čovjeku koji se njemu utječe!"},{"v":10,"t":"$JOD Bojte se Jahve, vi sveti njegovi: ne trpe oskudice koji ga se boje."},{"v":11,"t":"$KAF Osiromašiše mogućnici i gladuju, a koji traže Jahvu ne trpe oskudice."},{"v":12,"t":"$LAMED Dođite, djeco, i poslušajte me, učit ću vas strahu Gospodnjem."},{"v":13,"t":"$MEM O čovječe, ljubiš li život? Želiš li dane mnoge uživati dobra?"},{"v":14,"t":"$NUN Jezik svoj oda zla suspreži i usne od riječi prijevarnih!"},{"v":15,"t":"$SAMEK Zla se kloni, a čini dobro, traži mir i za njim idi!"},{"v":16,"t":"$PE Oči Jahvine gledaju pravedne, uši mu slušaju vapaje njihove."},{"v":17,"t":"$AJIN Lice se Jahvino okreće protiv zločinaca da im spomen zatre na zemlji."},{"v":18,"t":"$SADE Pravednici zazivaju, i Jahve ih čuje, izbavlja ih iz svih tjeskoba."},{"v":19,"t":"$KOF Blizu je Jahve onima koji su skršena srca, a klonule duše spasava."},{"v":20,"t":"$REŠ Mnoge nevolje ima pravednik, ali ga Jahve od svih izbavlja."},{"v":21,"t":"$ŠIN On čuva sve kosti njegove: ni jedna mu se neće slomiti."},{"v":22,"t":"$TAU Opakost bezbošca ubija, platit će koji mrze pravednika."},{"v":23,"t":"Jahve izbavlja duše slugu svojih, i neće platiti tko god se njemu utječe."}]},"35":{"hr":[{"v":1,"t":"Davidov. Optuži, Jahve, tužitelje moje i napadni one koji mene napadaju!"},{"v":2,"t":"Stavi oklop, uzmi štit svoj i ustani meni u pomoć!"},{"v":3,"t":"Zavitlaj kopljem i presretni progonitelje moje, reci mojoj duši: “Ja sam tvoje spasenje.”"},{"v":4,"t":"Nek' se smetu i postide koji život moj traže, nek' uzmaknu i nek' se posrame koji mi propast snuju!"},{"v":5,"t":"Nek' budu k'o pljeva na vjetru kad ih Anđeo Jahvin potjera!"},{"v":6,"t":"Mračni i skliski bili im putovi kad ih Anđeo Jahvin bude gonio!"},{"v":7,"t":"Bez razloga napeše mi mrežu, bez razloga grob duši mojoj iskopaše."},{"v":8,"t":"Propast će ih stići iznenada, u mrežu koju napeše sami će se uhvatiti, past će u jamu što je iskopaše!"},{"v":9,"t":"A moja će duše klicati u Jahvi, radovat će se u spasenju njegovu."},{"v":10,"t":"Sve će kosti moje govoriti: Tko je, Jahve, poput tebe koji ubogog spasavaš od silnika, jadnika i siromaha od pljačkaša?"},{"v":11,"t":"Ustadoše svjedoci opaki: pitaju me za ono što ne znam."},{"v":12,"t":"Vraćaju mi zlo za dobro, duša moja zapada u osamu."},{"v":13,"t":"U bolesti njihovoj nosio sam kostrijet, dušu svoju postom morio, i molitva mi se u krilo vraćala."},{"v":14,"t":"Kao za prijateljem, za bratom - obilažah tužan; od žalosti se pogurih kao onaj što za majkom žali."},{"v":15,"t":"A sada kad posrnuh ja, oni se raduju, skupiše se protiv mene da udare iznenada, i bez prestanka oni me razdiru."},{"v":16,"t":"Ruglom na ruglo iskušavaju me i zubima škripaju na mene."},{"v":17,"t":"O Jahve, dokle ćeš gledati? Istrgni mi dušu nasrtajima njihovim, otmi lavovima jedino dobro moje!"},{"v":18,"t":"Zahvalit ću ti u velikom zboru, slavit ću te među pukom brojnim."},{"v":19,"t":"Nek' se ne raduju nada mnom dušmani nepravedni, nek' ne namiguju očima oni koji me nizašto mrze!"},{"v":20,"t":"Jer oni ne misle o miru, već spletke snuju protiv mirnih u zemlji."},{"v":21,"t":"Razvaljuju svoja usta na me i govore: “Ha, ha, vidjesmo očima svojim!”"},{"v":22,"t":"Ti sve vidiš, o Jahve! Nemoj šutjeti! Gospode, od mene se ne udaljuj!"},{"v":23,"t":"Preni se, ustani da me obraniš, Bože moj, Gospode, vodi parnicu moju!"},{"v":24,"t":"Po svojoj me pravdi sudi, Jahve, Bože moj, nek' se ne raduju nada mnom!"},{"v":25,"t":"Nek' ne misle u srcu: “Ispunila nam se želja!” Nek' ne reknu: “Progutali smo ga!”"},{"v":26,"t":"Nek' se postide i posrame svi zajedno koji se nesreći mojoj raduju! Nek' se odjenu stidom i sramotom oni koji se podižu na me!"},{"v":27,"t":"Nek' radosno kliču kojima je pravo moje na srcu i nek' svagda govore: “Velik je Jahve! Milo mu je spasenje sluge njegova!”"},{"v":28,"t":"A moj će jezik kazivati pravdu tvoju i hvalu tebi navijeke."}]},"36":{"hr":[{"v":1,"t":"Zborovođi. Od sluge Jahvina Davida."},{"v":2,"t":"Grešan je naum u srcu zlotvora, straha Božjega nema on pred očima."},{"v":3,"t":"Sam sebi on laska suviše, grijeha svog ne vidi i ne mrzi."},{"v":4,"t":"Riječi usta njegovih prijevara su i zlodjelo, za razumnost i dobro on više ne mari."},{"v":5,"t":"Bezakonje smišlja na postelji svojoj, na opaku ostaje putu, od zla ne odustaje."},{"v":6,"t":"Do neba je, Jahve, dobrota tvoja, do oblaka vjernost tvoja."},{"v":7,"t":"Pravednost je tvoja k'o Božji vrhunci, a sudovi tvoji k'o duboko more: ljude i stoku ti, Jahve, spasavaš."},{"v":8,"t":"Kako li je dragocjena, Bože, dobrota tvoja, pod sjenu krila tvojih ljudi se sklanjaju;"},{"v":9,"t":"site se pretilinom Doma tvojega, potocima svojih slasti ti ih napajaš."},{"v":10,"t":"U tebi je izvor životni, tvojom svjetlošću mi svjetlost vidimo."},{"v":11,"t":"Zakrili dobrotom sve koji te štuju i pravednošću svojom sve koji su srca čestita."},{"v":12,"t":"Neka me ne zgazi noga ohola, i ruka grešnika neka me ne goni."},{"v":13,"t":"Gle, padoše koji čine bezakonje: oboreni su da više ne ustanu."}]},"37":{"hr":[{"v":1,"t":"Davidov. $ALEF Nemoj se žestiti na opake, zavidjet nemoj pakosnicima:"},{"v":2,"t":"kao trava brzo se osuše, k'o mlada zelen brzo uvenu."},{"v":3,"t":"$BET U Jahvu se uzdaj i čini dobro, da smiješ stanovati u zemlji i živjeti u miru."},{"v":4,"t":"Sva radost tvoja neka bude Jahve: on će ispuniti želje tvoga srca!"},{"v":5,"t":"$GIMEL Prepusti Jahvi putove svoje, u njega se uzdaj i on će sve voditi."},{"v":6,"t":"Pravda će tvoja zasjati k'o svjetlost i tvoje pravo k'o sunce podnevno."},{"v":7,"t":"$DALET Smiri se pred Jahvom i njemu se nadaj, ne žesti se na onog koji ima sreće, na čovjeka koji spletke kuje."},{"v":8,"t":"$HE Stišaj svoj gnjev i ostavi se srdžbe, ne žesti se da zlo ne učiniš."},{"v":9,"t":"Jer će biti satrti zlikovci, a koji se u Jahvu uzdaju, baštinit će zemlju."},{"v":10,"t":"$VAU Još malo i nestat će bezbožnika: mjesto ćeš njegovo tražiti, a njega više nema."},{"v":11,"t":"Zemlju će posjedovati krotki, obilje mira oni će uživat'."},{"v":12,"t":"$ZAJIN Bezbožnik smišlja zlo pravedniku i zubima škrguće na njega."},{"v":13,"t":"A Gospod se njemu smije jer vidi da dan njegov dolazi."},{"v":14,"t":"$HET Mač potežu bezbošci i zapinju lukove da obore jadnika i siromaha, da pokolju one koji hode pravim putem."},{"v":15,"t":"Mačem će vlastito srce probiti, slomit će se njihovi lukovi."},{"v":16,"t":"$TET Bolje je i malo u pravednika no golemo blago u zlotvora:"},{"v":17,"t":"jer će se ruke zlotvora slomiti, a Jahve je oslon pravedniku."},{"v":18,"t":"$JOD Jahve se brine za život čestitih, dovijeka će trajati baština njihova."},{"v":19,"t":"Neće se postidjeti u vrijeme nevolje, bit će siti u danima gladi."},{"v":20,"t":"$KAF A bezbožnici će propasti, dušmani Jahvini povenut će k'o ures livada, poput dima se rasplinuti."},{"v":21,"t":"$LAMED Bezbožnik zaima, ali ne vraća, pravednik se sažaljeva i daje."},{"v":22,"t":"Oni koje Jahve blagoslovi baštinit će zemlju, a koje prokune bit će zatrti."},{"v":23,"t":"$MEM Jahve vodi i učvršćuje korake čovjeku i mio mu je put njegov."},{"v":24,"t":"Ako i posrne, ne pada jer ga Jahve drži za ruku."},{"v":25,"t":"$NUN Mlad bijah i ostarjeh, al' ne vidjeh pravednika napuštena ili da mu djeca kruha prose."},{"v":26,"t":"Uvijek je milosrdan i u zajam daje, na njegovu je potomstvu blagoslov."},{"v":27,"t":"$SAMEK Zla se kloni i čini dobro, i ostat ćeš dovijeka."},{"v":28,"t":"Jer Jahve ljubi pravdu i pobožnika svojih ne ostavlja. $AJIN Zauvijek će biti zatrti zlikovci, istrijebit će se potomstvo bezbožnika."},{"v":29,"t":"Zemlju će posjedovati pravednici i živjet će na njoj dovijeka."},{"v":30,"t":"$PE Pravednikova usta mudrost kazuju, a jezik njegov govori pravo."},{"v":31,"t":"Zakon mu je Božji u srcu, ne kolebaju se koraci njegovi."},{"v":32,"t":"$SADE Bezbožnik vreba pravednoga i smišlja da ga usmrti."},{"v":33,"t":"Jahve ga neće ostaviti u njegovoj vlasti i neće dopustiti da ga na sudu osude."},{"v":34,"t":"$KOF U Jahvu se uzdaj i drži se puta njegova: on će te uzvisit' i baštinit ćeš zemlju; radostan ćeš gledati propast bezbožnih."},{"v":35,"t":"$REŠ Vidjeh obijesna zlotvora gdje se k'o cedar krošnjat širi."},{"v":36,"t":"Prođoh, i gle - nema ga više; potražih ga i ne nađoh."},{"v":37,"t":"$ŠIN Promatraj čestita i gledaj neporočna: mirotvorac ima potomstvo."},{"v":38,"t":"A grešnici bit će svi iskorijenjeni, istrijebit će se zlikovačko sjeme."},{"v":39,"t":"$TAU Od Jahve dolazi spas pravednicima, on im je zaklon u vrijeme nevolje."},{"v":40,"t":"Jahve im pomaže, on ih izbavlja: on će ih izbaviti od zlotvora i spasiti, jer u njemu traže okrilje."}]},"38":{"hr":[{"v":1,"t":"Psalam. Davidov. Za spomen."},{"v":2,"t":"Jahve, u srdžbi svojoj nemoj ne karati, i nemoj me kazniti u svojemu gnjevu."},{"v":3,"t":"Strijele se tvoje u me zabodoše, ruka me tvoja teško pritisnu:"},{"v":4,"t":"na tijelu mi ništa zdravo nema zbog gnjeva tvog, od grijeha mojih mira mi nema kostima."},{"v":5,"t":"Zloće moje glavu su mi nadišle, kao preteško breme tište me."},{"v":6,"t":"Rane moje zaudaraju i gnjiju zbog bezumnosti moje."},{"v":7,"t":"Pogurih se sav i zgrčih, povazdan lutam žalostan."},{"v":8,"t":"Moji bokovi puni su ognjice, na tijelu mi ništa zdravo nema."},{"v":9,"t":"Iscrpljen sam i satrven posve, stenjem od jecanja srca svojega."},{"v":10,"t":"O Gospode, sve su mi želje pred tobom, i vapaji moji nisu ti skriveni."},{"v":11,"t":"Srce mi udara silno, snaga me ostavlja i svjetlost vida očinjeg gasi se."},{"v":12,"t":"Prijatelji i drugovi od rana mojih uzmakoše, i moji najbliži stoje daleko."},{"v":13,"t":"Namještaju mi zamke oni koji mi život vrebaju, koji mi žele nesreću, propašću mi prijete i uvijek smišljaju prijevare."},{"v":14,"t":"A ja sam kao gluh i ništa ne čujem i, kao nijem, usta ne otvaram."},{"v":15,"t":"Postadoh k'o čovjek koji ne čuje i koji u ustima nema odgovora."},{"v":16,"t":"Jer u tebe se, o Jahve, uzdam, ti ćeš me uslišati, Jahve, Bože moj!"},{"v":17,"t":"Rekoh: “Nek' se ne raduju nada mnom; kad mi noga posrne, nek' se ne uzdižu nada mnom!”"},{"v":18,"t":"Jer umalo ne propadoh, i moja je bol svagda preda mnom."},{"v":19,"t":"Bezakonje svoje ja priznajem i pun sam žalosti zbog grijeha svojega."},{"v":20,"t":"A koji su bez razloga protiv mene, moćni su, i mnogi su koji me mrze nepravedno."},{"v":21,"t":"Za dobro zlom mi uzvraćaju, protive mi se što tražim dobro."},{"v":22,"t":"O Jahve, ne ostavljaj me! Bože moj, ne udaljuj se od mene!"},{"v":23,"t":"Požuri se meni u pomoć, Gospode, spase moj!"}]},"39":{"hr":[{"v":1,"t":"Zborovođi. Jedutunu. Psalam. Davidov."},{"v":2,"t":"Odlučio sam: “Čuvat ću put svoj da ne zgriješim jezikom; usta ću svoja zauzdati dokle god preda mnom bude bezbožnik.”"},{"v":3,"t":"Zamukoh, zanijemjeh, glasa ne puštah, ali uzalud - bol mi postade gorča."},{"v":4,"t":"U meni srce je gorjelo, na samu pomisao buknuo bi oganj; tad progovorih svojim jezikom:"},{"v":5,"t":"“Objavi mi, Jahve, moj svršetak i kolika je mjera mojih dana, da znam kako sam ništavan."},{"v":6,"t":"Evo, pedljem si mi dane izmjerio, život moj je kao ništa pred tobom: tek dašak je svaki čovjek."},{"v":7,"t":"Poput sjene čovjek prolazi tek dašak je sve bogatstvo njegovo: zgrće, a ne zna tko će ga pokupiti.”"},{"v":8,"t":"A sada, čemu da se nadam, Gospode? Sva je nada moja u tebi!"},{"v":9,"t":"Izbavi me svih mojih bezakonja, ne daj da ruglo budem luđaku!"},{"v":10,"t":"Šutim i usta ne otvaram, jer tako si ti učinio."},{"v":11,"t":"Bič svoj otkloni od mene, jer izdišem pod težinom ruke tvoje."},{"v":12,"t":"Ti kaznama popravljaš čovjeka i sve mu najdraže kao moljac rastačeš: tek dašak je svaki čovjek."},{"v":13,"t":"Čuj, o Jahve, molitvu moju, vapaje mi poslušaj, na suze se moje ne ogluši! Jer u tebe ja sam došljak, pridošlica kao svi oci moji."},{"v":14,"t":"Odvrati pogled od mene, da odahnem prije nego odem i više ne budem!"}]},"40":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"Uzdah se u Jahvu uzdanjem silnim, i on se k meni prignu i usliša vapaj moj."},{"v":3,"t":"Izvuče me iz jame propasti, iz blata kalnoga; noge mi stavi na hridinu, korake moje ukrijepi."},{"v":4,"t":"U usta mi stavi pjesmu novu, slavopoj Bogu našemu. Vidjet će mnogi i strah će ih obuzeti: uzdanje će svoje staviti u Jahvu."},{"v":5,"t":"Blago čovjeku koji se u Jahvu uzda, koji ne ide za štovateljima lažnih bogova, za onima koji se predaju prijevari."},{"v":6,"t":"Čudesa mnoga tvoriš, o Jahve, Bože moj, i namisli čudesne - ravna ti nema! Kazivat' ih i objavljivati želim, al' odveć ih je da bi se nabrojit' mogli."},{"v":7,"t":"Nisu ti mile ni žrtve ni prinosi, nego si mi uši otvorio: paljenice ni okajnice ne tražiš."},{"v":8,"t":"Tada rekoh: “Evo dolazim! U svitku knjige piše za mene:"},{"v":9,"t":"Milje mi je, Bože moj, vršit volju tvoju, Zakon tvoj duboko u srcu ja nosim.”"},{"v":10,"t":"Tvoju ću pravdu naviještat' u velikom zboru, i usta svojih zatvoriti neću, o Jahve, sve ti je znano."},{"v":11,"t":"Tvoju pravdu neću kriti u srcu, kazivat ću vjernost tvoju i tvoj spas. Tajit neću dobrote tvoje, ni tvoje vjernosti velikoj skupštini."},{"v":12,"t":"A ti, o Jahve, milosrđa mi svog ne krati, dobrota tvoja i vjernost neka me svagda čuvaju."},{"v":13,"t":"Jer me okružiše nesreće nebrojene, krivice me moje sustigoše da gledat' ne mogu: više ih je no vlasi na glavi, i srce mi je stoga klonulo."},{"v":14,"t":"Bilo ti milo, o Jahve, da me izbaviš; Gospodine, u pomoć mi pohitaj!"},{"v":15,"t":"Neka se postide i smetu svi koji mi o glavi rade. Nek' uzmaknu i neka se posrame koji se nesreći mojoj raduju!"},{"v":16,"t":"Neka se skamene u sramoti svojoj koji zlurado na me grohoću!"},{"v":17,"t":"Neka kliču i nek' se vesele u tebi svi koji te traže! Neka govore svagda: “Velik je Jahve!” svi koji spasenje tvoje ljube."},{"v":18,"t":"Bijedan sam ja i nevoljan, al' Jahve se brine za me. Ti si pomoć moja i moj spasitelj; o Bože moj, ne kasni!"}]},"41":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"Blago onome koji misli na uboga i slaba: u dan nevolje Jahve će ga spasiti!"},{"v":3,"t":"Jahve će ga štititi i živa sačuvati, sreću mu dati na zemlji i neće ga predati na volju dušmanima."},{"v":4,"t":"Jahve će ga ukrijepiti na postelji boli, bolest mu okrenuti u snagu."},{"v":5,"t":"Zavapih: “Jahve, smiluj mi se, iscijeli mi dušu jer tebi sagriješih!”"},{"v":6,"t":"Neprijatelji zlo govore o meni: “Kad će umrijeti i kad će mu nestati imena?”"},{"v":7,"t":"I dođe li tko da me posjeti, himbeno govori, u srcu pakosti skuplja i vani opada."},{"v":8,"t":"Mrzitelji moji svi složno šapuću o meni; zlo mi dosuđuju:"},{"v":9,"t":"“Pogubna se pošast na nj oborila.” Ili: “Tko jednom leže, više ne ustaje.”"},{"v":10,"t":"Pa i prijatelj moj u koga se uzdah, koji blagovaše kruh moj, petu na me podiže."},{"v":11,"t":"A ti, Jahve, smiluj se meni i podigni me da im mogu uzvratiti."},{"v":12,"t":"Po tome ću znati da sam mio tebi: što se dušmanin moj neće veseliti nada mnom."},{"v":13,"t":"A mene ćeš zdrava uzdržati i pred svoje me lice staviti dovijeka."},{"v":14,"t":"Blagoslovljen Jahve, Bog Izraelov, od vijeka do vijeka! Tako neka bude! Amen!"}]},"42":{"hr":[{"v":1,"t":"Zborovođi. Poučna pjesma. Sinova Korahovih."},{"v":2,"t":"Kao što košuta žudi za izvor-vodom, tako duša moja čezne, Bože, za tobom."},{"v":3,"t":"Žedna mi je duša Boga, Boga živoga: o, kada ću doći i lice Božje gledati?"},{"v":4,"t":"Suze su kruh moj danju i noću, dok me svednevice pitaju: “Gdje ti je Bog tvoj?”"},{"v":5,"t":"Duša moja gine kada se spomenem kako koračah u mnoštvu predvodeć' ih k Domu Božjem uz radosno klicanje i hvalopojke u povorci svečanoj."},{"v":6,"t":"Što si mi, dušo, klonula i što jecaš u meni? U Boga se uzdaj, jer opet ću ga slaviti, spasenje svoje, Boga svog!"},{"v":7,"t":"Tuguje duša u meni, stoga se tebe spominjem iz zemlje Jordana i Hermona, s brda Misara."},{"v":8,"t":"Bezdan doziva bezdan bukom slapova tvojih: sve vode tvoje i vali preko mene prijeđoše."},{"v":9,"t":"Nek' mi danju Jahve naklonost udijeli, a noću pjesmom ću hvalit' Boga života svog."},{"v":10,"t":"Reći ću Bogu: “Hridino moja, zašto me zaboravljaš? Zašto obilazim žalostan, pritisnut dušmanima?”"},{"v":11,"t":"Kosti mi se lome od poruge neprijatelja dok me svednevice pitaju: “Gdje ti je Bog tvoj?”"},{"v":12,"t":"Što si mi, dušo, klonula i što jecaš u meni? U Boga se uzdaj, jer opet ću ga slaviti, spasenje svoje, Boga svog!"}]},"43":{"hr":[{"v":1,"t":"Dosudi mi pravo, Bože, i povedi parbu moju protiv čeljadi bezbožne, izbavi me od čovjeka zlobna i opaka!"},{"v":2,"t":"Jer ti si, Bože, zaklon moj: zašto me odbacuješ? Zašto obilazim žalostan, pritisnut dušmanima?"},{"v":3,"t":"Pošlji svjetlost svoju i vjernost: nek' me vode, nek' me dovedu na tvoju svetu goru, u šatore tvoje!"},{"v":4,"t":"I pristupit ću Božjem žrtveniku, Bogu, radosti svojoj. Harfom ću slaviti tebe, Bože, o Bože moj!"},{"v":5,"t":"Što si mi, dušo, klonula i što jecaš u meni? U Boga se uzdaj, jer opet ću ga slaviti, spasenje svoje, Boga svog!"}]},"44":{"hr":[{"v":1,"t":"Zborovođi. Sinova Korahovih. Poučna pjesma."},{"v":2,"t":"Bože, ušima svojim slušasmo, očevi nam pripovijedahu naši, o djelu koje si izveo u danima njihovim - u danima davnim."},{"v":3,"t":"Rukom si svojom izagnao pogane, a njih posadio, iskorijenio narode, a njih raširio."},{"v":4,"t":"Mačem svojim oni zemlju ne zauzeše niti im mišica njihova donese pobjedu, već desnica tvoja i tvoja mišica i lice tvoje milosno jer si ih ljubio."},{"v":5,"t":"Ti, o moj Kralju i Bože moj, ti si dao pobjede Jakovu."},{"v":6,"t":"Po tebi dušmane svoje odbismo, u tvome imenu zgazismo one koji se na nas digoše."},{"v":7,"t":"U svoj se luk nisam pouzdavao, nit' me mač moj spasavao."},{"v":8,"t":"Nego ti, ti si nas spasio od dušmana, ti si postidio one koji nas mrze."},{"v":9,"t":"Dičili smo se Bogom u svako doba i tvoje ime slavili svagda."},{"v":10,"t":"A sad si nas odbacio i posramio nas i više ne izlaziš, Bože, sa četama našim."},{"v":11,"t":"Pustio si da pred dušmanima uzmaknemo, i opljačkaše nas mrzitelji naši."},{"v":12,"t":"Dao si nas k'o ovce na klanje i rasuo nas među neznabošce."},{"v":13,"t":"U bescjenje si puk svoj prodao i obogatio se nisi prodajom."},{"v":14,"t":"Učinio si nas ruglom susjedima našim, na podsmijeh i igračku onima oko nas."},{"v":15,"t":"Na porugu smo neznabošcima, narodi kimaju glavom nad nama."},{"v":16,"t":"Svagda mi je sramota moja pred očima i stid mi lice pokriva"},{"v":17,"t":"zbog pogrdne graje podrugljivaca, zbog osvetljiva dušmanina."},{"v":18,"t":"Sve nas to snađe iako te nismo zaboravili niti povrijedili Saveza tvoga,"},{"v":19,"t":"niti nam se srce odmetnulo od tebe, niti nam je noga s tvoje skrenula staze,"},{"v":20,"t":"kad si nas smrvio u boravištu šakalskom i smrtnim nas zavio mrakom."},{"v":21,"t":"Da smo i zaboravili ime Boga našega, da smo ruke k tuđem bogu podigli:"},{"v":22,"t":"zar Bog toga ne bi saznao? TÓa on poznaje tajne srdaca!"},{"v":23,"t":"Ali zbog tebe ubijaju nas dan za danom, i mi smo im k'o ovce za klanje."},{"v":24,"t":"Preni se! Što spavaš, Gospode? Probudi se! Ne odbacuj nas dovijeka!"},{"v":25,"t":"Zašto lice svoje sakrivaš, zaboravljaš bijedu i nevolju našu?"},{"v":26,"t":"Jer duša nam se u prah raspala, trbuh nam se uza zemlju prilijepio."},{"v":27,"t":"Ustani, u pomoć nam priteci, izbavi nas radi ljubavi svoje!"}]},"45":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Ljiljani”. Sinova Korahovih. Poučna pjesma. Svadbena pjesma."},{"v":2,"t":"Iz srca mi naviru riječi divne: pjesmu svoju ja kralju pjevam, jezik mi je k'o pisaljka hitra pisara."},{"v":3,"t":"Lijep si, najljepši od ljudskih sinova, po usnama ti se milina prosula, stoga te Bog blagoslovio dovijeka."},{"v":4,"t":"Pripaši mač uz bedra, junače, ogrni se sjajem i veličanstvom!"},{"v":5,"t":"Zajaši i kreni za istinu, za vjernost i pravdu, zapni luk i desnicu svoju proslavi!"},{"v":6,"t":"Oštre su strelice tvoje, narodi padaju pred tobom i kraljeve dušmane ostavlja hrabrost."},{"v":7,"t":"Prijestolje je tvoje, Bože, u vijeke vjekova, i pravedno žezlo - žezlo je tvog kraljevstva!"},{"v":8,"t":"Ti ljubiš pravednost, a mrziš bezakonje, stoga Jahve, Bog tvoj, tebe pomaza uljem radosti kao nikog od tvojih drugova."},{"v":9,"t":"Smirnom, alojem i kasijom mirišu ti haljine, iz dvorova bjelokosnih harfe te vesele."},{"v":10,"t":"Kraljevske ti kćeri idu u susret, zdesna ti je kraljica u zlatu ofirskom."},{"v":11,"t":"“Slušaj, kćeri, pogledaj, prisluhni: zaboravi svoj narod i dom oca svog!"},{"v":12,"t":"Zaželi li kralj ljepotu tvoju, smjerno se pokloni njemu jer je on gospodar tvoj."},{"v":13,"t":"Narod tirski dolazi s darovima, naklonost tvoju traže prvaci naroda.”"},{"v":14,"t":"Sva lijepa korača kći kraljeva u haljinama zlatom vezenim."},{"v":15,"t":"U haljini od veza šarena kralju je dovode, pratnja su joj djevice, druge njezine."},{"v":16,"t":"S veseljem ih vode i s klicanjem u kraljeve dvore ulaze."},{"v":17,"t":"Oce tvoje naslijedit će tvoji sinovi, postavit ćeš ih knezovima na svoj zemlji."},{"v":18,"t":"Iz koljena u koljeno naviještat će ime tvoje, hvalit će te narodi u vijeke vjekova."}]},"46":{"hr":[{"v":1,"t":"Zborovođi. Sinova Korahovih. Po napjevu “Djevice”. Pjesma."},{"v":2,"t":"Bog nam je zaklon i utvrda, pomoćnik spreman u nevolji."},{"v":3,"t":"Stoga, ne bojmo se kad se ljulja zemlja, kad se bregovi ruše u more."},{"v":4,"t":"Nek' buče i bjesne valovi morski, nek' bregovi dršću od žestine njihove: s nama je Jahve nad Vojskama, naša je utvrda Bog Jakovljev!"},{"v":5,"t":"Rijeka i rukavci njezini vesele Grad Božji, presveti šator Višnjega."},{"v":6,"t":"Bog je sred njega, poljuljat se neće, od rane zore Bog mu pomaže."},{"v":7,"t":"Ma bješnjeli puci, rušila se carstva, kad glas njegov zagrmi, zemlja se rastopi:"},{"v":8,"t":"s nama je Jahve nad Vojskama, naša je utvrda Bog Jakovljev!"},{"v":9,"t":"Dođite, gledajte djela Jahvina, strahote koje on na zemlji učini."},{"v":10,"t":"Do nakraj zemlje on ratove prekida, lukove krši i lomi koplja, štitove ognjem sažiže."},{"v":11,"t":"Prestanite i znajte da sam ja Bog, uzvišen nad pucima, nad svom zemljom uzvišen!"},{"v":12,"t":"S nama je Jahve nad Vojskama, naša je utvrda Bog Jakovljev!"}]},"47":{"hr":[{"v":1,"t":"Zborovođi. Sinova Korahovih. Psalam."},{"v":2,"t":"Narodi svi, plješćite rukama, kličite Bogu glasom radosnim."},{"v":3,"t":"Jer Jahve je to - svevišnji, strašan, kralj velik nad zemljom svom."},{"v":4,"t":"Narode je nama podložio, pogane stavio pod noge naše,"},{"v":5,"t":"baštinu nam odabrao - ponos Jakova, svoga ljubimca."},{"v":6,"t":"Uzlazi Bog uz klicanje, Jahve uza zvuke trublje."},{"v":7,"t":"Pjevajte Bogu, pjevajte, pjevajte kralju našemu, pjevajte!"},{"v":8,"t":"Jer on je kralj nad zemljom svom, pjevajte Bogu, pjevači vrsni!"},{"v":9,"t":"Bog kraljuje nad narodima, stoluje Bog na svetom prijestolju."},{"v":10,"t":"Prvaci se pribiru poganski k narodu Boga Abrahamova. Božji su svi vlastodršci zemlje, nad svima on je uzvišen."}]},"48":{"hr":[{"v":1,"t":"Pjesma. Psalam. Sinova Korahovih."},{"v":2,"t":"Velik je Jahve, hvale predostojan u gradu Boga našega."},{"v":3,"t":"Sveto brdo njegovo, brijeg veličanstven, radost je zemlji svoj. Gora Sion, na krajnjem sjeveru, grad je Kralja velikog."},{"v":4,"t":"Bog u kulama njegovim jakom se pokaza utvrdom."},{"v":5,"t":"Jer gle, složiše se kraljevi, navališe zajedno."},{"v":6,"t":"Čim vidješe, zapanjiše se i zbunjeni u bijeg nagnuše."},{"v":7,"t":"Ondje ih trepet obuze kao muka porodilje,"},{"v":8,"t":"kao kad vjetar istočni razbija brodove taršiške."},{"v":9,"t":"Što smo čuli, sada vidimo: grad Jahve nad Vojskama, grad Boga našega - Bog ga utvrdi dovijeka."},{"v":10,"t":"Spominjemo se, Bože, tvoje dobrote usred Hrama tvojega."},{"v":11,"t":"Kao ime tvoje, Bože, tako i slava tvoja do nakraj zemlje doseže. Puna je pravde desnica tvoja; neka se raduje brdo sionsko!"},{"v":12,"t":"Neka kliču gradovi Judini zbog tvojih sudova!"},{"v":13,"t":"Obiđite Sion i prođite njime, prebrojite kule njegove!"},{"v":14,"t":"Pogledajte dobro bedeme njegove, promotrite mu potanko dvorove: da biste kazivali budućem koljenu:"},{"v":15,"t":"“Takav je Bog, Bog naš zasvagda i dovijeka! On neka nas vodi!”"}]},"49":{"hr":[{"v":1,"t":"Zborovođi. Sinova Korahovih. Psalam."},{"v":2,"t":"Poslušajte ovo, svi narodi, čujte, svi stanovnici zemlje,"},{"v":3,"t":"vi, djeco puka, i vi, odličnici, bogati i siromašni zajedno!"},{"v":4,"t":"Moja će usta zboriti mudrost, i moje srce misli razumne."},{"v":5,"t":"K poučnoj izreci priklonit ću uho, uz harfu ću izložit' svoju zagonetku."},{"v":6,"t":"Što da se bojim u danima nesreće kad me opkoli zloba izdajica"},{"v":7,"t":"koji se u blago svoje uzdaju i silnim se hvale bogatstvom?"},{"v":8,"t":"TÓa nitko sebe ne može otkupit' ni za se dati Bogu otkupninu:"},{"v":9,"t":"životu je cijena previsoka, i nikada je neće platiti"},{"v":10,"t":"tko želi živjeti dovijeka i ne vidjeti jamu grobnu."},{"v":11,"t":"Jer, i mudri umiru, pogiba i luđak i bezumnik: bogatstvo svoje ostavlja drugima."},{"v":12,"t":"Grobovi im kuće zasvagda, stanovi njihovi od koljena do koljena, sve ako se zemlje nazivale imenima njihovim."},{"v":13,"t":"Čovjek koji nerazumno živi sličan je stoci koja ugiba."},{"v":14,"t":"Takav je put onih koji se ludo uzdaju, to je konac onih koji uživaju u sreći:"},{"v":15,"t":"Poput stada redaju se u Podzemlju, smrt im je pastir, a dobri njima vladaju. Njihova će lika brzo nestati, Podzemlje će im biti postojbina."},{"v":16,"t":"A moju će dušu Bog ugrabiti Podzemlju iz pandža i milostivo me primiti."},{"v":17,"t":"Ne boj se ako se tko obogati i ako se poveća blago doma njegova:"},{"v":18,"t":"kad umre, ništa neće ponijeti sa sobom, i blago njegovo neće s njime sići."},{"v":19,"t":"Ako se u životu držao sretnim - “Govorit će se da ti je dobro bilo!” -"},{"v":20,"t":"i on će doći u skup otaca svojih, gdje svjetlosti više vidjeti neće."},{"v":21,"t":"Čovjek koji nerazumno živi sličan je stoci koja ugiba."}]},"50":{"hr":[{"v":1,"t":"Psalam. Asafov. Bog nad bogovima, Jahve, govori i zove zemlju od izlaza sunčeva do zalaza."},{"v":2,"t":"Sa Siona predivnog Bog zablista:"},{"v":3,"t":"Bog naš dolazi i ne šuti. Pred njim ide oganj što proždire, oko njega silna bjesni oluja."},{"v":4,"t":"On zove nebesa odozgo i zemlju da sudi narodu svojemu:"},{"v":5,"t":"“Saberite mi sve pobožnike koji žrtvom Savez sa mnom sklopiše!”"},{"v":6,"t":"Nebesa objavljuju pravednost njegovu: on je Bog sudac!"},{"v":7,"t":"“Slušaj, narode moj, ja ću govoriti, o Izraele, svjedočit ću protiv tebe: ja, Bog - Bog tvoj!"},{"v":8,"t":"Ne korim te zbog žrtava tvojih - paljenice su tvoje svagda preda mnom."},{"v":9,"t":"Neću od doma tvog' uzet junca, ni jaraca iz tvojih torova:"},{"v":10,"t":"tÓa moje su sve životinje šumske, tisuće zvjeradi u gorama mojim."},{"v":11,"t":"Znam sve ptice nebeske, moje je sve što se miče u poljima."},{"v":12,"t":"Kad bih ogladnio, ne bih ti rekao, jer moja je zemlja i sve što je ispunja."},{"v":13,"t":"Zar da ja jedem meso bikova ili da pijem krv jaraca?"},{"v":14,"t":"Prinesi Bogu žrtvu zahvalnu, ispuni Višnjemu zavjete svoje!"},{"v":15,"t":"I zazovi me u dan tjeskobe: oslobodit ću te, a ti ćeš me slaviti.”"},{"v":16,"t":"A grešniku Bog progovara: “Što tumačiš naredbe moje, što mećeš u usta Savez moj?"},{"v":17,"t":"Ti, komu stega ne prija, te riječi moje iza leđa bacaš?"},{"v":18,"t":"Kad tata vidiš, s njime se bratimiš i družiš se s preljubnicima."},{"v":19,"t":"Svoja si usta predao pakosti, a jezik ti plete prijevare."},{"v":20,"t":"U društvu na brata govoriš i kaljaš sina matere svoje."},{"v":21,"t":"Sve si to činio, a ja da šutim? Zar misliš da sam ja tebi sličan? Pokarat ću te i stavit ću ti sve to pred oči.”"},{"v":22,"t":"Shvatite ovo svi vi koji Boga zaboraviste, da vas ne pograbim i nitko vas spasiti neće."},{"v":23,"t":"Pravo me štuje onaj koji prinosi žrtvu zahvalnu: i onomu koji hodi stazama pravim - njemu ću pokazati spasenje svoje."}]},"51":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov. Kad je k Davidu došao prorok Natan poslije njegova grijeha"},{"v":2,"t":"Smiluj mi se, Bože, po milosrđu svome, po velikom smilovanju izbriši moje bezakonje!"},{"v":3,"t":"Operi me svega od moje krivice, od grijeha me mojeg očisti!"},{"v":4,"t":"Bezakonje svoje priznajem, grijeh je moj svagda preda mnom."},{"v":5,"t":"Tebi, samom tebi ja sam zgriješio i učinio što je zlo pred tobom: pravedan ćeš biti kad progovoriš, bez prijekora kada presudiš."},{"v":6,"t":"Evo, grešan sam već rođen, u grijehu me zače majka moja."},{"v":7,"t":"Evo, ti ljubiš srce iskreno, u dubini duše učiš me mudrosti."},{"v":8,"t":"Poškropi me izopom da se očistim, operi me, i bit ću bjelji od snijega!"},{"v":9,"t":"Objavi mi radost i veselje, nek' se obraduju kosti satrvene!"},{"v":10,"t":"Odvrati lice od grijeha mojih, izbriši svu moju krivicu!"},{"v":11,"t":"Čisto srce stvori mi, Bože, i duh postojan obnovi u meni!"},{"v":12,"t":"Ne odbaci me od lica svojega i svoga svetog duha ne uzmi od mene!"},{"v":13,"t":"Vrati mi radost svoga spasenja i učvrsti me duhom spremnim!"},{"v":14,"t":"Učit ću bezakonike tvojim stazama, i grešnici tebi će se obraćati."},{"v":15,"t":"Oslobodi me od krvi prolivene, Bože, Bože spasitelju moj! Nek' mi jezik kliče pravednosti tvojoj!"},{"v":16,"t":"Otvori, Gospodine, usne moje, i usta će moja naviještati hvalu tvoju."},{"v":17,"t":"Žrtve ti se ne mile, kad bih dao paljenicu, ti je ne bi primio."},{"v":18,"t":"Žrtva Bogu duh je raskajan, srce raskajano, ponizno, Bože, nećeš prezreti."},{"v":19,"t":"U svojoj dobroti milostiv budi Sionu i opet sagradi jeruzalemske zidine!"},{"v":20,"t":"Tada će ti biti mile žrtve pravedne i tad će se prinosit' teoci na žrtveniku tvojemu."}]},"52":{"hr":[{"v":1,"t":"Zborovođi. Poučna pjesma. Davidova. Kad je Edomac Doeg Šaulu javio: “David je ušao u kuću Abimelekovu."},{"v":2,"t":"Što se to hvališ pakošću, silniče nesmiljeni?"},{"v":3,"t":"Neprestano snuješ o propasti, jezik ti je britva nabrušena, spletkaru!"},{"v":4,"t":"Zlo voliš više nego dobro, i laž više nego pravednost!"},{"v":5,"t":"Mili su ti pogubni govori, lažljivi jeziče!"},{"v":6,"t":"Bog će te zato satrti, zauvijek te ukloniti; iščupat će te iz tvog šatora, iskorijeniti iz zemlje živih."},{"v":7,"t":"Pravednici će gledati s užasom i njemu se smijati:"},{"v":8,"t":"“Gle čovjeka koji ne uze Boga za svoju zaštitu, već se uzdao u veliko bogatstvo i osilio u svojim zločinima!”"},{"v":9,"t":"A ja, k'o zelena maslina u Domu Božjem, uzdam se u Božju dobrotu dovijeka."},{"v":10,"t":"Hvalit ću te svagda što si to učinio i slavit ću tvoje ime, jer je dobrostivo, pred licem tvojih pobožnika."}]},"53":{"hr":[{"v":1,"t":"Zborovođi. Prema napjevu “Bolest”. Poučna pjesma. Davidova."},{"v":2,"t":"Bezumnik reče u srcu: “Nema Boga!” Pokvareni rade gadosti; nitko da čini dobro."},{"v":3,"t":"Bog s nebesa gleda na sinove ljudske da vidi ima li tko razuman Boga da traži."},{"v":4,"t":"No svi skrenuše zajedno, svi se pokvariše: nitko da čini dobro - nikoga nema."},{"v":5,"t":"Neće li se urazumiti svi što čine bezakonje, koji proždiru narod moj kao da jedu kruh? Boga oni ne zazivlju:"},{"v":6,"t":"od straha će drhtat' gdje straha i nema jer Bog će rasuti kosti onih koji tebe opsjedaju, bit će posramljeni jer će ih Bog odbaciti."},{"v":7,"t":"O, neka dođe sa Siona spas Izraelu! Kad Bog promijeni udes naroda svoga, klicat će Jakov, radovat' se Izrael."}]},"54":{"hr":[{"v":1,"t":"Zborovođi. Uza žičana glazbala. Poučna pjesma. Davidova. Kad su Zifijci došli k Šaulu govoreći: “David se kod nas"},{"v":2,"t":"Spasi me, Bože, svojim imenom i jakošću svojom izbori mi pravdu!"},{"v":3,"t":"Poslušaj, Bože, moju molitvu i usliši riječi usta mojih!"},{"v":4,"t":"Oholice ustadoše na me i moj život traže silnici: na Boga se ne osvrću."},{"v":5,"t":"Evo, Bog mi pomaže, Gospodin krijepi život moj."},{"v":6,"t":"Okreni nesreću na dušmane moje, zatri ih u vjernosti svojoj."},{"v":7,"t":"Od srca rado ću ti žrtvovati, slavit ću ti ime, Jahve, jer je dobrostivo,"},{"v":8,"t":"jer ti me izbavi iz svake nevolje, i oko moje vidje postiđene moje dušmane."}]},"55":{"hr":[{"v":1,"t":"Zborovođi. Uza žičana glazbala. Poučna pjesma. Davidova."},{"v":2,"t":"Počuj mi, Bože, molitvu, ne krij se molbi mojoj:"},{"v":3,"t":"obazri se na me i usliši me! Mučim se u svojoj tjeskobi,"},{"v":4,"t":"zbuni me vika dušmanska i tlačenje grešničko. Navališe na me nesrećom, bijesno me progone."},{"v":5,"t":"Srce mi je ustreptalo i strah me samrtni spopade."},{"v":6,"t":"Užas me i trepet hvata, groza me obuze."},{"v":7,"t":"Zavapih: “O, da su mi krila golubinja, odletio bih da otpočinem!"},{"v":8,"t":"Daleko, daleko bih letio, u pustinji se nastanio;"},{"v":9,"t":"brzo bih si potražio sklonište od bijesne oluje i vihora.”"},{"v":10,"t":"Smeti ih, Gospode, podvoji im jezike, jer nasilje i svađu vidim u gradu;"},{"v":11,"t":"danju i noću zidinama kruže; bezakonja su i nevolje u njemu."},{"v":12,"t":"Usred njega zasjede, s ulica mu nepravda i podlost ne odlaze."},{"v":13,"t":"Da me pogrdio dušmanin, bio bih podnio; da se digao na me koji me mrzi, pred njim bih se sakrio."},{"v":14,"t":"Ali ti, ti si to bio, meni jednak, prijatelj moj, moj pouzdanik"},{"v":15,"t":"s kojim sam slatko drugovao i složno hodismo u Domu Božjemu."},{"v":16,"t":"Smrt neka ih zaskoči, živi nek' siđu u Podzemlje jer im je pakost u stanu i srcu."},{"v":17,"t":"A ja ću Boga prizvati, i Jahve će me spasiti."},{"v":18,"t":"Večerom, jutrom i o podne tužan ću jecati, i on će čuti vapaj moj."},{"v":19,"t":"Dat će mi mira od onih koji me progone: jer mnogi su protiv mene."},{"v":20,"t":"Bog će čuti i njih poniziti, Onaj koji kraljuje odvijeka, jer se ne popravljaju, Boga se ne boje."},{"v":21,"t":"Podižu ruke na prijatelje, savez svoj oskvrnjuju."},{"v":22,"t":"Usta su im glađa od maslaca, a srce ratoborno; riječi blaže od ulja, a oni - isukani mačevi."},{"v":23,"t":"Povjeri Jahvi svu svoju brigu, i on će te pokrijepiti: neće dati da ikada posrne pravednik."},{"v":24,"t":"A njih ti, o Bože, strmoglavi u jamu grobnu! Krvoloci i varalice ni polovicu dana neće doživjeti! A ja se u tebe uzdam!"}]},"56":{"hr":[{"v":1,"t":"Zborovođi. Prema napjevu “Golubica nijema u daljini”. Davidov. Miktam. Kad su ga u Gatu uhitili Filistejci."},{"v":2,"t":"Smiluj mi se, moj Bože, jer me dušmanin hoće zgaziti, napadač me moj neprestano tlači."},{"v":3,"t":"Dušmani moji nasrću na me povazdan, mnogo ih je koji se na me obaraju. Svevišnji,"},{"v":4,"t":"kad me strah spopadne, u te ću se uzdati."},{"v":5,"t":"Božje obećanje slavim, u Boga ja se uzdam i neću se bojati: što mi može učiniti smrtnik?"},{"v":6,"t":"Od jutra do večeri obružuju me, svi naumi njihovi meni su na zlo."},{"v":7,"t":"Sastaju se i vrebaju, paze mi na korake, o glavi mi rade."},{"v":8,"t":"Plati im prema bezakonju, u gnjevu, o Bože, obori pogane!"},{"v":9,"t":"Ti izbroji dane mog progonstva, sabrao si suze moje u mijehu svom. Nije li sve zapisano u knjizi tvojoj?"},{"v":10,"t":"Moji će dušmani uzmaknuti čim te zazovem. Ovo sigurno znam: Bog je za mene!"},{"v":11,"t":"Božje obećanje slavim,"},{"v":12,"t":"u Jahvu se uzdam i neću se bojati: što mi može učiniti čovjek?"},{"v":13,"t":"Vežu me zavjeti koje učinih tebi, o Bože: prinijet ću ti žrtve zahvalne"},{"v":14,"t":"jer si mi dušu od smrti spasio. Ti si očuvao noge moje od pada, da pred Bogom hodim u svjetlosti živih."}]},"57":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Ne pogubi!” Davidov. Miktam. Kad je ispred Šaula pobjegao u pećinu."},{"v":2,"t":"Smiluj mi se, Bože, o smiluj se meni jer mi se duša utječe tebi! U sjenu tvojih krila zaklanjam se dok pogibao ne mine."},{"v":3,"t":"Vapijem Bogu višnjemu, Bogu koji mi čini dobro."},{"v":4,"t":"Nek' pošalje s nebesa i spasi me, nek' postidi one što me progone: neka Bog pošalje dobrotu svoju i vjernost!"},{"v":5,"t":"Ležim usred lavova koji proždiru ljudske sinove. Zubi su im koplja i strijele, a jezik im mač je naoštren."},{"v":6,"t":"Uzvisi se, Bože, nad nebesa, slava tvoja nek' je nad svom zemljom!"},{"v":7,"t":"Mrežu namjestiše stopama mojim, stisnuše dušu moju; iskopaše preda mnom jamu: sami nek' u nju padnu!"},{"v":8,"t":"Postojano je srce moje, Bože, postojano je srce moje; pjevat ću i svirati."},{"v":9,"t":"Probudi se, dušo moja! Probudi se, harfo i citaro! Probudit ću zoru jutarnju."},{"v":10,"t":"Hvalit ću te, Gospode, među narodima, među pucima pjevat ću tebi:"},{"v":11,"t":"jer do neba je dobrota tvoja, do oblaka vjernost tvoja."},{"v":12,"t":"Uzvisi se, Bože, nad nebesa, slava tvoja nek' je nad svom zemljom!"}]},"58":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Ne pogubi!” Davidov. Miktam."},{"v":2,"t":"Zar doista krojite pravdu, vi moćni, zar sudite pravo, sinovi ljudski?"},{"v":3,"t":"Ne, već bezakonje smišljeno činite, po zemlji vam ruke dijele nepravde."},{"v":4,"t":"Na krivu su putu bezbošci od krila majčina, na krivu su putu lašci od utrobe."},{"v":5,"t":"U njima je otrov kao u zmije, kao u ljutice što uši začepljuje"},{"v":6,"t":"da glas čarobnjakov ne čuje ni glas bajača vješta bajanju."},{"v":7,"t":"O Bože, polomi im zube u ustima; razbij, o Jahve, čeljusti lavićima!"},{"v":8,"t":"K'o vode što hitro otječu neka se razliju, k'o zgažena trava neka se osuše."},{"v":9,"t":"Nek' budu k'o puž koji se pužuć' rastoči, k'o pometnut plot nek' sunca ne vide."},{"v":10,"t":"Prije nego vam kotlovi trnje osjete, dok je zeleno, neka ga vihor odnese."},{"v":11,"t":"Radostan će biti pravednik kad ugleda odmazdu, noge će prati u krvi zlotvora."},{"v":12,"t":"I reći će ljudi: “Pravednik plod svoj ima! Još ima Boga da sudi na zemlji!”"}]},"59":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Ne pogubi!” Davidov. Miktam. Kad je Šaul opkolio kuću da ubije Davida."},{"v":2,"t":"Izbavi me od dušmana, Bože moj, zaštiti me od mojih protivnika!"},{"v":3,"t":"Izbavi me od bezakonika, od krvoloka spasi me!"},{"v":4,"t":"Jer evo: dušu moju vrebaju, na me ustadoše silnici. Nema na meni krivnje, o Jahve, ni grijeha:"},{"v":5,"t":"bez moje krivnje na me nasrću. Probudi se! Dođi mi u pomoć i pogledaj,"},{"v":6,"t":"Jahve, Bože nad Vojskama, Bože Izraelov! Preni se, kazni sve pogane, podlacima nemoj se smilovati!"},{"v":7,"t":"Uvečer se vraćaju, reže poput pasa i trče po gradu."},{"v":8,"t":"Gle, kako bljuju ustima; kletve su im na usnama i govore: “Tko nas čuje?”"},{"v":9,"t":"No, ti im se smiješ, o Jahve, i rugaš se poganima svima."},{"v":10,"t":"Jakosti moja, gledat ću na te, jer ti si, Bože, zaštita moja, Bog moj, milosrđe moje."},{"v":11,"t":"Bog neka mi pohiti u susret, nek' me razveseli nad dušmanima mojim!"},{"v":12,"t":"Pobij ih, Bože, da mi narod ne zavode, zbuni i obori ih jakošću svojom, štite naš, Gospodine."},{"v":13,"t":"Grijeh je svaka riječ usta njihovih: nek se uhvate u svoju oholost, u kletve i laži što ih govore!"},{"v":14,"t":"Istrijebi ih u gnjevu, istrijebi da nestanu, nek' se zna da Bog vlada u Jakovu i do nakraj zemlje!"},{"v":15,"t":"Uvečer se vraćaju, reže poput pasa i trče po gradu."},{"v":16,"t":"Nek' lutaju okolo tražeći hranu; i kad se nasite, neka zavijaju."},{"v":17,"t":"A ja ću opjevati silu tvoju i klicat ću jutrom milosrđu tvome, jer mi ti postade utočište i sklonište u dan nevolje."},{"v":18,"t":"Jakosti moja, tebi ću pjevati, jer ti si, Bože, zaštita moja, Bog moj, milosrđe moje."}]},"60":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Ljiljan svjedočanstva”. Miktam. Davidov. Kad je David izišao protiv Aram Naharajima i protiv Aram Sobe i kad je Joab na povratku potukao dvanaest tisuća Edomaca"},{"v":2,"t":"Bože, ti nas ÓodbÄaci i bojne nam redove prÓobi, razjari se, a sad nas opet vrati!"},{"v":3,"t":"Potrese zemlju, rasječe je, zatvori joj usjeline jer se poljuljala."},{"v":4,"t":"Zlu si kob na svoj narod navalio, napio nas vinom omamnim."},{"v":5,"t":"Al' si i stijeg dao vjernicima svojim da umaknu luku dušmanskom."},{"v":6,"t":"Da ti se ljubimci izbave, desnicom pomozi, usliši nas!"},{"v":7,"t":"Bog reče u svom Svetištu: “Šekem ću razdijelit' kličući, dolinu Sukot izmjeriti."},{"v":8,"t":"Moj je Gilead, moj Manaše, Efrajim mi kaciga, Judeja žezlo moje!"},{"v":9,"t":"Moab je sud iz kojeg se umivam, na Edom ću baciti obuću, nad Filistejcem slavit' pobjedu!”"},{"v":10,"t":"Tko će me dovesti do utvrđena grada, tko će me dovesti do Edoma?"},{"v":11,"t":"Zar nećeš ti, o Bože, što nas odbaci? Zar više nećeš, Bože, s četama našim?"},{"v":12,"t":"Pomozi nam protiv dušmana, jer ljudska je pomoć ništavna!"},{"v":13,"t":"S pomoću Božjom hrabro ćemo se boriti, a on će zgaziti naše dušmane."}]},"61":{"hr":[{"v":1,"t":"Zborovođi. Uza žičana glazbala. Davidov."},{"v":2,"t":"O Bože, vapaj mi poslušaj, budi pomnjiv na molitvu moju!"},{"v":3,"t":"S kraja zemlje vapijem k tebi jer mi srce klonu. Dignut ćeš me na liticu i pokoj mi dati,"},{"v":4,"t":"jer ti si moje sklonište, utvrda čvrsta protiv dušmana."},{"v":5,"t":"O, da mi je stanovati uvijek u tvom šatoru, da se sklanjat' mogu pod okrilje tvoje!"},{"v":6,"t":"Jer ti, Bože, usliši molbe moje, dade mi baštinu onih što ime ti štuju."},{"v":7,"t":"Kraljevim danima pridometni danÄa, kroz koljena mnoga nek' mu ljeta traju,"},{"v":8,"t":"nek' pred Bogom uvijek vlada; dobrotu i vjernost pošalji da ga čuvaju!"},{"v":9,"t":"Ovako ću pjevat svagda tvom imenu, dan za danom vršit' zavjete svoje."}]},"62":{"hr":[{"v":1,"t":"Zborovođi. Po Jedutunu. Psalam. Davidov."},{"v":2,"t":"Samo je u Bogu mir, dušo moja, samo je u njemu spasenje."},{"v":3,"t":"Samo on je moja hrid i spasenje, utvrda moja: neću se pokolebati."},{"v":4,"t":"Dokle ćete na bijednika nasrtati, obarat' ga svi zajedno, k'o zid ruševan il' ogradu nagnutu?"},{"v":5,"t":"Urotiše se da me s visa mog obore, u laži uživaju; ustima blagoslivlju, a u srcu proklinju."},{"v":6,"t":"Samo je u Bogu mir, dušo moja, samo je u njemu nada moja."},{"v":7,"t":"Samo on je moja hrid i spasenje, utvrda moja: neću se pokolebati."},{"v":8,"t":"U Boga je spasenje moje i slava; Bog mi je hridina silna, utočište."},{"v":9,"t":"U nj se, narode, uzdaj u svako doba; pred njim srca izlijevajte: Bog je naše utočište!"},{"v":10,"t":"Sinovi su ljudski samo dašak, laž su djeca čovječja: svi da stanu na tezulju, od daha bi lakši bili."},{"v":11,"t":"U grabež se ne uzdajte nit' se otetim tašto hvalite; umnoži l' se blago, nek' vam srce za nj ne prione."},{"v":12,"t":"Bog rekao jedno, a ja dvoje čuo:"},{"v":13,"t":"“U Boga je snaga! U tebe je, Gospode, dobrota! Ti uzvraćaš svakom po djelima.”"}]},"63":{"hr":[{"v":1,"t":"Psalam. Davidov. Dok David bijaše u Judejskoj pustinji."},{"v":2,"t":"O Bože, ti si Bog moj: gorljivo tebe tražim; tebe žeđa duša moja, tebe želi tijelo moje, kao zemlja suha, žedna, bezvodna."},{"v":3,"t":"U Svetištu sam tebe motrio gledajuć' ti moć i slavu."},{"v":4,"t":"Ljubav je tvoja bolja od života, moje će te usne slavit'."},{"v":5,"t":"Tako ću te slavit' za života, u tvoje ću ime ruke dizati."},{"v":6,"t":"Duša će mi biti kao sala i mrsa sita, hvalit ću te kliktavim ustima."},{"v":7,"t":"Na postelji se tebe spominjem, u bdjenjima noćnim mislim na tebe."},{"v":8,"t":"Ti postade meni pomoć, kličem u sjeni krila tvojih."},{"v":9,"t":"Duša se moja k tebi privija, desnica me tvoja drži."},{"v":10,"t":"Oni što dušu u propast guraju neka siđu u dubinu zemlje,"},{"v":11,"t":"nek' vlasti mača predani budu, nek' postanu plijen šakalima."},{"v":12,"t":"A kralj će se radovat' u Bogu, slavit će se tko se kune njime, jer će lašcima biti začepljena usta."}]},"64":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"Poslušaj, Bože, moje žalbe glas; od strašna dušmanina život mi čuvaj!"},{"v":3,"t":"Štiti me od mnoštva opakih, sakrij od bjesnila zlotvora"},{"v":4,"t":"koji bruse jezike k'o mačeve, otrovne riječi izbacuju kao strijele,"},{"v":5,"t":"da iz potaje rane nedužna, da ga rane iznenada ne bojeć' se ničega."},{"v":6,"t":"Spremni su na djelo pakosno, snuju kako će kradom zamke staviti i govore: “Tko će nas vidjeti?”"},{"v":7,"t":"Snuju zlodjela, smišljene osnove kriju: pamet i srce čovječje bezdan su duboki."},{"v":8,"t":"No Bog ih ranjava strijelom, odjednom ih rane prekriju."},{"v":9,"t":"Vlastiti jezik propast im donosi, kimaju glavom oni što ih vide:"},{"v":10,"t":"svi se boje, Božje djelo slave i misle o onom što on učini."},{"v":11,"t":"Pravednik se raduje u Jahvi, njemu se utječe, i kliču svim srcem čestiti."}]},"65":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov. Pjesma."},{"v":2,"t":"Bože, tebi dolikuje hvalospjev sa Sionu, tebi se ispunja zavjet -"},{"v":3,"t":"ti molitve uslišuješ. Svaka pÓut dolazi k tebi"},{"v":4,"t":"pod teretom grijeha. Naši nas prijestupi taru, ti ih pomiruješ."},{"v":5,"t":"Blažen kog izabra i k sebi uze: on boravi u dvorima tvojim. Daj da se nasitimo dobrima Doma tvoga i svetošću tvoga Hrama."},{"v":6,"t":"Čudesno nas uslišuješ u pravednosti svojoj, o Bože, spasenje naše, nado svih krajeva svijeta i mora dalekih."},{"v":7,"t":"Učvršćuješ bregove jakošću svojom silom opasÄan."},{"v":8,"t":"Krotiš huku mora, huku valova i buku naroda."},{"v":9,"t":"Oni što žive nakraj svijeta boje se znamenja tvojih; dveri jutra i večeri radošću napunjaš."},{"v":10,"t":"Ti pÓohodÄi zemlju i ti je nÓatopÄi, ÓobogatÄi nju veoma. Božja se rijeka vodom napuni, ti pripravi ljudima žito. Ovako pripremi zemlju:"},{"v":11,"t":"brazde joj natopi, grude joj poravna; kišom je omekša, usjeve joj blagoslovi."},{"v":12,"t":"Ti okruni godinu dobrotom svojom, plodnost niče za stopama tvojim."},{"v":13,"t":"Pustinjski pašnjaci kaplju od obilja, brežuljci se pašu radošću."},{"v":14,"t":"Njive se kite stadima, doline se pokrivaju žitom: svagdje klicanje, pjesma."}]},"66":{"hr":[{"v":1,"t":"Zborovođi. Pjesma. Psalam."},{"v":2,"t":"Kliči Bogu, zemljo sva, opjevaj slavu imena njegova, podaj mu hvalu dostojnu."},{"v":3,"t":"Recite Bogu: “Kako su potresna djela tvoja! Zbog velike sile tvoje dušmani ti laskaju."},{"v":4,"t":"Sva zemlja nek' ti se klanja i nek' ti pjeva, neka pjeva tvom imenu!”"},{"v":5,"t":"Dođite i gledajte djela Božja: čuda učini među sinovima ljudskim."},{"v":6,"t":"On pretvori more u zemlju suhu te rijeku pregaziše. Stog' se njemu radujmo!"},{"v":7,"t":"Dovijeka vlada jakošću svojom, oči mu paze na narode da se ne izdignu ljudi buntovni."},{"v":8,"t":"Blagoslivljajte, narodi, Boga našega, razglašujte hvalu njegovu!"},{"v":9,"t":"Našoj je duši darovao život i ne dade da nam posrne noga."},{"v":10,"t":"Iskušavao si nas teško, Bože, iskušavao ognjem kao srebro."},{"v":11,"t":"Pustio si da u zamku padnemo, stisnuo lancima bokove naše."},{"v":12,"t":"Pustio si da nam zajašu za vrat: prošli smo kroz oganj i vodu, onda si pustio da odahnemo."},{"v":13,"t":"S paljenicama ću u Dom tvoj ući, zavjete ispuniti pred tobom"},{"v":14,"t":"što ih obećaše usne moje, što ih usta moja u tjeskobi obrekoše."},{"v":15,"t":"Prinijet ću ti paljenice s kadom ovnova, žrtvovati volove i jarad."},{"v":16,"t":"Dođite, počujte, koji se Boga bojite, pripovjedit ću što učini duši mojoj!"},{"v":17,"t":"Na svoja sam usta njega zvao, jezikom ga hvalio."},{"v":18,"t":"Da sam u srcu na zlo mislio, ne bi uslišio Gospod."},{"v":19,"t":"No Bog me uslišio: obazro se na glas molitve moje."},{"v":20,"t":"Blagoslovljen Bog koji mi molitvu ne odbi, naklonosti ne odvrati od mene!"}]},"67":{"hr":[{"v":1,"t":"Zborovođi. Uza žičana glazbala. Psalam. Pjesma."},{"v":2,"t":"Smilovao nam se Bog i blagoslovio nas, obasjao nas licem svojim,"},{"v":3,"t":"da bi sva zemlja upoznala putove tvoje, svi puci tvoje spasenje!"},{"v":4,"t":"Neka te slave narodi, Bože, svi narodi neka te slave!"},{"v":5,"t":"Nek' se vesele i kliču narodi, jer sudiš pucima pravedno i narode vodiš na zemlji."},{"v":6,"t":"Neka te slave narodi, Bože, svi narodi neka te slave!"},{"v":7,"t":"Zemlja plodom urodila! Bog nas blagoslovio, Bog naš!"},{"v":8,"t":"Bog nas blagoslovio! Neka ga štuju svi krajevi svjetski!"}]},"68":{"hr":[{"v":1,"t":"Zborovođi. Davidov. Psalam. Pjesma."},{"v":2,"t":"Bog nek' ustane! Razbježali se dušmani njegovi! Svi mrzitelji njegovi pobjegli pred njim!"},{"v":3,"t":"Kao što dim iščezava, i njih neka nestane! Kako se vosak topi na ognju, nek' nestane grešnika pred licem Božjim!"},{"v":4,"t":"Pravedni neka se raduju, neka klikću pred Bogom, neka kliču od radosti."},{"v":5,"t":"Pjevajte Bogu, slavite mu ime! Poravnajte put onome koji ide pustinjom - kojemu je ime Jahve - i kličite pred njim!"},{"v":6,"t":"Otac sirota, branitelj udovica, Bog je u svom svetom šatoru."},{"v":7,"t":"Napuštene okućit će Jahve, sužnjima pružit' sretnu slobodu: buntovnici samo ostaše u sažganoj pustinji."},{"v":8,"t":"Kad si stupao, Bože, pred narodom svojim, dok si prolazio pustinjom,"},{"v":9,"t":"tresla se zemlja, nebo se rosilo pred Bogom, Sinaj drhtao pred Bogom, Bogom Izraela."},{"v":10,"t":"Blagoslovljen dažd pustio si, Bože, na baštinu svoju, okrijepio je umornu."},{"v":11,"t":"Stado se tvoje nastani u njoj, u dobroti, Bože, ti je spremi siromahu."},{"v":12,"t":"Jahve riječ zadaje, veliko je mnoštvo radosnih vjesnika:"},{"v":13,"t":"kraljevi vojska bježe te bježe, domaćice plijen dijele."},{"v":14,"t":"Dok vi počivaste među stadima, krila golubice zablistaše srebrom, a njeno perje žućkastim zlatom:"},{"v":15,"t":"ondje Svemogući razbijaše kraljeve, a ona poput snijega zablista na Salmonu."},{"v":16,"t":"Božanska je gora gora bašanska vrletna."},{"v":17,"t":"Zašto vi, gore vrletne, zavidno gledate na goru gdje se svidje Bogu prebivati? Jahve će na njoj boraviti svagda!"},{"v":18,"t":"Božja su kola bezbrojna, tisuću tisuća: Jahve sa Sinaja u Svetište dolazi!"},{"v":19,"t":"Na visinu uzađe vodeći sužnje, na dar si ljude primio, pa i one što ne žele prebivati kod Boga."},{"v":20,"t":"Blagoslovljen Jahve dan za danom, nosi nas Bog, naš Spasitelj."},{"v":21,"t":"Bog naš jest Bog koji spasava, Jahve od smrti izbavlja."},{"v":22,"t":"Zaista, Bog će satrti glave dušmana svojih, kuštravo tjeme onog što hodi u grijesima."},{"v":23,"t":"Reče Gospodin: “Iz Bašana ću ih dovesti, dovest ću ih iz dubine mora,"},{"v":24,"t":"da okupaš nogu u krvi, da jezici tvojih pasa imadnu dio od dušmana.”"},{"v":25,"t":"Ulazak ti, Bože, gledaju, ulazak moga Boga i Kralja u Svetište:"},{"v":26,"t":"sprijeda pjevači, za njima svirači, u sredini djevojke s bubnjićima."},{"v":27,"t":"“U svečanim zborovima slavite Boga, slavite Jahvu, sinovi Izraelovi!”"},{"v":28,"t":"Predvodi ih najmlađi, Benjamin, koji ide pred njima, ondje su knezovi Judini sa četama svojim, knezovi Zebulunovi i knezovi Naftalijevi."},{"v":29,"t":"Pokaži, Bože, silu svoju, silu kojom se, Bože, boriš za nas"},{"v":30,"t":"iz Hrama svojega u Jeruzalemu! Nek' ti kraljevi darove donose!"},{"v":31,"t":"Ukroti neman u trsci, stado bikova s teladi naroda! Neka se prostru pred tobom sa srebrnim žezlima: rasprši narode koji se ratu vesele!"},{"v":32,"t":"Nek' dođu velikani iz Egipta, Etiopija nek' pruži ruke Bogu!"},{"v":33,"t":"Sva kraljevstva svijeta, pjevajte Bogu, slavite Jahvu,"},{"v":34,"t":"koji se vozi po nebu, po nebu iskonskom! Čuj, glasom grmi, glasom svojim silnim:"},{"v":35,"t":"“Priznajte silu Božju!” Nad Izraelom veličanstvo njegovo, u oblacima sila njegova!"},{"v":36,"t":"Strašan je Bog iz svojega Svetišta. Bog Izraelov daje moć i silu narodu svojemu. Blagoslovljen Bog!"}]},"69":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Ljiljani”. Davidov."},{"v":2,"t":"Spasi me, Bože: vode mi dođoše do grla!"},{"v":3,"t":"U duboko blato zapadoh i nemam kamo nogu staviti; u duboku tonem vodu, pokrivaju me valovi."},{"v":4,"t":"Iznemogoh od vikanja, grlo mi je promuklo, oči mi klonuše Boga mog čekajuć'."},{"v":5,"t":"Brojniji su od vlasi na glavi mojoj oni koji me mrze nizašto. Tvrđi su od kostiju mojih oni što mi se nepravedno protive: zar mogu vratiti što nisam oteo?"},{"v":6,"t":"Bože, ti znadeš bezumnost moju, moji ti grijesi nisu sakriti."},{"v":7,"t":"Nek' se ne postide zbog mene koji se u te uzdaju, Gospode, Jahve nad Vojskama! Neka se ne posrame zbog mene koji traže tebe, Bože Izraelov!"},{"v":8,"t":"Jer zbog tebe podnesoh pogrdu, i stid mi pokri lice."},{"v":9,"t":"Tuđinac postadoh braći i stranac djeci majke svoje."},{"v":10,"t":"Jer me izjela revnost za Dom tvoj i poruge onih koji se rugaju tebi padoše na me."},{"v":11,"t":"Dušu sam postom mučio, okrenulo mi se u ruglo."},{"v":12,"t":"Uzeh kostrijet za haljinu, i postah im igračka."},{"v":13,"t":"Koji sjede na vratima protiv mene govore, vinopije mi rugalice poju."},{"v":14,"t":"No tebi se molim, Jahve, u vrijeme milosti, Bože; po velikoj dobroti svojoj ti me usliši po svojoj vjernoj pomoći!"},{"v":15,"t":"Izvuci me iz blata da ne potonem, od onih koji me mrze izbavi me - iz voda dubokih."},{"v":16,"t":"Nek' me ne pokriju valovi, nek' me ne proguta dubina, nek' bezdan ne zatvori usta nada mnom!"},{"v":17,"t":"Usliši me, Jahve, jer je dobrostiva milost tvoja, po velikom milosrđu pogledaj na me!"},{"v":18,"t":"Ne sakrivaj lica pred slugom svojim; jer sam u stisci, usliši me brzo!"},{"v":19,"t":"Približi se duši mojoj i spasi je; zbog dušmana mojih oslobodi me!"},{"v":20,"t":"Ti mi znadeš porugu, stid i sramotu, pred tvojim su očima svi koji me muče."},{"v":21,"t":"Ruganje mi slomilo srce i klonuh; čekao sam da se tko sažali nada mnom, ali ga ne bi; i da me tko utješi, ali ga ne nađoh."},{"v":22,"t":"U jelo mi žuči umiješaše, u mojoj me žeđi octom napojiše."},{"v":23,"t":"Nek' im stol bude zamka, a žrtvene gozbe stupica!"},{"v":24,"t":"Nek' im potamne oči da ne vide, nek' im bokovi zasvagda oslabe!"},{"v":25,"t":"Izlij na njih ljutinu, žar tvoga gnjeva nek' ih zahvati!"},{"v":26,"t":"Njihova kuća nek' opusti, u njihovu šatoru nek' nitko ne stanuje!"},{"v":27,"t":"Jer su progonili koga ti pokara, bol povećaše onomu koga ti rani."},{"v":28,"t":"Na njihovu krivnju krivnju još dodaj, ne opravdali se pred tobom!"},{"v":29,"t":"Nek' budu izbrisani iz knjige živih, među pravednike neka se ne broje!"},{"v":30,"t":"A ja sam jadnik i bolnik - nek' me štiti tvoja pomoć, o Bože!"},{"v":31,"t":"Božje ću ime hvaliti popijevkom, hvalit ću ga zahvalnicom."},{"v":32,"t":"Bit će to milije Jahvi no bik žrtveni, milije nego junac s papcima i rozima."},{"v":33,"t":"Gledajte, ubogi, i radujte se, nek' vam oživi srce, svima koji Boga tražite."},{"v":34,"t":"Jer siromahe Jahve čuje, on ne prezire sužanja svojih."},{"v":35,"t":"Neka ga hvale nebesa i zemlja, mora i sve što se u njima miče."},{"v":36,"t":"Jer Bog će spasiti Sion - on će sagradit' gradove Judine - tu će oni stanovat', imati baštinu."},{"v":37,"t":"Baštinit će ga potomci slugu njegovih; prebivat će u njemu oni što ljube ime Božje."}]},"70":{"hr":[{"v":1,"t":"Zborovođi. Davidov. Za spomen."},{"v":2,"t":"O Bože, spasi me, Jahve, u pomoć mi pohitaj!"},{"v":3,"t":"Nek' se postide i smetu svi koji mi o glavi rade! Nek' odstupe i nek' se posrame koji se nesreći mojoj raduju!"},{"v":4,"t":"Nek' uzmaknu u sramoti svojoj koji zlurado na me grohoću!"},{"v":5,"t":"Neka kliču i nek' se vesele u tebi svi koji tebe traže! Neka govore svagda: “Velik je Bog!” svi koji spasenje tvoje ljube!"},{"v":6,"t":"A bijedan sam ja i nevoljan, o Bože, u pomoć mi pohitaj! Ti si pomoć moja i spasitelj; Jahve, ne kasni!"}]},"71":{"hr":[{"v":1,"t":"Tebi si, Jahve, utječem, ne daj da se ikada postidim!"},{"v":2,"t":"U pravdi me svojoj spasi i izbavi, prikloni uho k meni i spasi me!"},{"v":3,"t":"Budi mi hrid utočišta i čvrsta utvrda spasenja: jer ti si stijena i utvrda moja."},{"v":4,"t":"Bože moj, istrgni me iz ruke zlotvora, iz šake silnika i tlačitelja:"},{"v":5,"t":"jer ti si, o Gospode, ufanje moje, Jahve, uzdanje od moje mladosti!"},{"v":6,"t":"Na te se oslanjam od utrobe; ti si mi zaštitnik od majčina krila: u te se svagda uzdam."},{"v":7,"t":"Mnogima postadoh čudo, jer ti si mi bio silna pomoć."},{"v":8,"t":"Usta mi bijahu puna tvoje hvale, slaviše te svaki dan!"},{"v":9,"t":"Ne zabaci me u starosti: kad mi malakšu sile, ne zapusti me!"},{"v":10,"t":"Jer govore o meni moji dušmani, i koji me vrebaju složno se svjetuju:"},{"v":11,"t":"“Bog ga je napustio; progonite ga i uhvatite jer nema tko da ga spasi!”"},{"v":12,"t":"O Bože, ne stoj daleko od mene, Bože moj, pohitaj mi u pomoć!"},{"v":13,"t":"Neka se postide i propadnu koji traže moj život; nek' se sramotom i stidom pokriju koji mi žele nesreću!"},{"v":14,"t":"A ja ću se uvijek uzdati, iz dana u dan hvaleć' te sve više."},{"v":15,"t":"Ustima ću naviještati pravednost tvoju, povazdan pomoć tvoju: jer im ne znam broja."},{"v":16,"t":"Kazivat ću silu Jahvinu, Gospode, slavit ću samo tvoju pravednost."},{"v":17,"t":"Bože, ti mi bijaše učitelj od mladosti moje, i sve do sada naviještam čudesa tvoja."},{"v":18,"t":"Ni u starosti, kad posijedim, Bože, ne zapusti me, da kazujem mišicu tvoju naraštaju novom i svima budućima silu tvoju,"},{"v":19,"t":"i pravednost tvoju, Bože, koja seže do neba, kojom učini velika djela. Bože, tko je kao ti!"},{"v":20,"t":"Trpljenja mnoga i velika bacio si na me: ali ti ćeš me opet oživiti i opet me podići iz dubine zemlje."},{"v":21,"t":"Povećaj dostojanstvo moje i opet me utješi:"},{"v":22,"t":"A ja ću uz harfu slaviti tvoju vjernost, o Bože, svirat ću ti u citaru, Sveče Izraelov!"},{"v":23,"t":"Moje će usne klicati pjevajuć' tebi i moja duša koju si spasio."},{"v":24,"t":"I moj će jezik svagda slaviti pravdu tvoju, jer su postiđeni i posramljeni oni što traže moju nesreću."}]},"72":{"hr":[{"v":1,"t":"Salomonov. Bože, sud svoj daj kralju i svoju pravdu sinu kraljevu."},{"v":2,"t":"Nek' puku tvojem sudi pravedno, siromasima po pravici!"},{"v":3,"t":"Nek' bregovi narodu urode mirom, a brežuljci pravdom."},{"v":4,"t":"Sudit će pravo ubogim pučanima, djeci siromaha donijet će spasenje, a tlačitelja on će smrviti."},{"v":5,"t":"I živjet će dugo kao sunce i kao mjesec u sva pokoljenja."},{"v":6,"t":"Sići će kao rosa na travu, kao kiša što natapa zemlju!"},{"v":7,"t":"U danima njegovim cvjetat će pravda i mir velik - sve dok bude mjeseca."},{"v":8,"t":"I vladat će od mora do mora i od Rijeke do granica svijeta."},{"v":9,"t":"Dušmani će njegovi preda nj kleknuti i protivnici lizati prašinu."},{"v":10,"t":"Kraljevi Taršiša i otoka nosit će dare, vladari od Arabije i Sabe danak donositi."},{"v":11,"t":"Klanjat će mu se svi vladari, svi će mu narodi služiti."},{"v":12,"t":"On će spasiti siromaha koji uzdiše, nevoljnika koji pomoćnika nema;"},{"v":13,"t":"smilovat će se ubogu i siromahu i spasit će život nevoljniku:"},{"v":14,"t":"oslobodit će ih nepravde i nasilja, jer je dragocjena u njegovim očima krv njihova."},{"v":15,"t":"Stog' neka živi! Neka ga daruju zlatom iz Arabije, nek' mole za njega svagda i neka ga blagoslivljaju!"},{"v":16,"t":"Nek' bude izobila žita u zemlji, po vrhuncima klasje neka šušti k'o Libanon! I cvjetali stanovnici gradova kao trava na livadi."},{"v":17,"t":"Bilo ime njegovo blagoslovljeno dovijeka! Dok je sunca, živjelo mu ime! Njim se blagoslivljala sva plemena zemlje, svi narodi nazivali blaženima!"},{"v":18,"t":"Blagoslovljen Jahve, Bog Izraelov, koji jedini tvori čudesa!"},{"v":19,"t":"I blagoslovljeno slavno mu ime dovijeka! Sva se zemlja napunila slave njegove! Tako neka bude. Amen!"},{"v":20,"t":"Time se završavaju molitve Jišajeva sina Davida."}]},"73":{"hr":[{"v":1,"t":"Psalam. Asafov Kako je dobar Bog čestitima, Bog onima koji su čista srca!"},{"v":2,"t":"A meni umalo noge ne posrnuše, zamalo koraci ne okliznuše,"},{"v":3,"t":"jer zločincima zavidjeh motreći sreću grešnika."},{"v":4,"t":"Nikakvu patnju ne snose, pretilo je tijelo njihovo."},{"v":5,"t":"Ne žive u mukama smrtnika, ljudske ih nevolje ne biju."},{"v":6,"t":"Stoga je oholost ogrlica vratu njihovu, a nasilje haljina koja ih pokriva."},{"v":7,"t":"Iz pretila srca izlazi opakost njihova, srca im se prelijevaju ispraznim tlapnjama."},{"v":8,"t":"Podsmjehuju se i zlobno govore, nasiljem prijete odozgo."},{"v":9,"t":"Ustima na nebo nasrću, a jezik se njihov obara na zemlju."},{"v":10,"t":"Zato moj narod za njima leti i srče obilne vode"},{"v":11,"t":"pa veli: “Kako da dozna Bog? Spoznaje li Svevišnji?”"},{"v":12,"t":"Eto, takvi su grešnici: uvijek spokojni, bogatstvo zgrću."},{"v":13,"t":"Jesam li, dakle, samo ja uzalud čuvao srce čisto i u nedužnosti prao ruke"},{"v":14,"t":"kad sam primao udarce svaki dan i kaznu jutro za jutrom?"},{"v":15,"t":"Da sam kazao: “Govorit ću kao i oni”, izdao bih rod sinova tvojih."},{"v":16,"t":"Promišljah tada da bih spoznao: al' mi se učini mučno u očima mojim"},{"v":17,"t":"sve dok ne nađoh ulaz u Božje svetinje pa prozreh kakav im je svršetak."},{"v":18,"t":"Zaista, na klizavu stazu ti ih postavljaš, u propast ih obaraš."},{"v":19,"t":"Kako učas propadoše, nestaše, užas ih izjede!"},{"v":20,"t":"Kao što čovjek prezire san kad se probudi, tako ćeš, Gospode, prezreti lik im kada ustaneš."},{"v":21,"t":"Kad mi duša bijaše ojađena, a bubrezi probodeni,"},{"v":22,"t":"bezumnik bijah bez razbora, k'o živinče pred tobom."},{"v":23,"t":"Al' ću odsad uvijek biti s tobom, jer ti prihvati desnicu moju:"},{"v":24,"t":"vodit ćeš me po naumu svojem da me zatim uzmeš u slavu svoju."},{"v":25,"t":"Koga ja imam u nebu osim tebe? Kad sam s tobom, ne veselim se zemlji."},{"v":26,"t":"Malaksalo mi tijelo i srce: okrilje srca moga, i baštino moja, o Bože, dovijeka!"},{"v":27,"t":"Doista, propast će oni koji se udaljuju od tebe, istrebljuješ svakog tko ti se iznevjeri."},{"v":28,"t":"A meni je milina biti u Božjoj blizini, imati sklonište svoje u Jahvi. Pripovijedat ću sva tvoja djela na vratima Kćeri sionske."}]},"74":{"hr":[{"v":1,"t":"Poučna pjesma. Asafova. Zašto si, Bože, posve zabacio, zašto kiptiš gnjevom na ovce paše svoje?"},{"v":2,"t":"Sjeti se zajednice koju si davno stekao, plÓemena koje namače kao svoju baštinu i brda Siona gdje si Šator svoj udario!"},{"v":3,"t":"Korakni k ruševinama vječnim - sve je u Svetištu razorio neprijatelj."},{"v":4,"t":"Protivnici tvoji vikahu posred skupštine tvoje, znakove svoje postaviše k'o pobjedne znakove."},{"v":5,"t":"Bijahu kao oni koji mašu sjekirom po guštari,"},{"v":6,"t":"sjekirom i maljem vrata mu razbijali."},{"v":7,"t":"Ognju predadoše Svetište tvoje, do zemlje oskvrnuše Prebivalište tvoga imena."},{"v":8,"t":"Rekoše u srcu: “Istrijebimo ih zajedno; spalite sva svetišta Božja na zemlji!”"},{"v":9,"t":"Ne vidimo znakova svojih, proroka više nema, i nitko među nama ne zna dokle ..."},{"v":10,"t":"Dokle će se još, o Bože, dušmanin rugati? Hoće li protivnik dovijeka prezirati ime tvoje?"},{"v":11,"t":"Zašto povlačiš ruku, zašto u krilu sakrivaš desnicu svoju?"},{"v":12,"t":"No Bog je moj kralj od davnine, on koji posred zemlje spasava!"},{"v":13,"t":"Ti svojom silom rasječe more, smrska glave nakazama u vodi."},{"v":14,"t":"Ti si Levijatanu glave zdrobio, dao ga za hranu nemanima morskim."},{"v":15,"t":"Ti si dao da provre izvor i bujica, ti si presušio rijeke nepresušne."},{"v":16,"t":"Tvoj je dan i noć je tvoja, ti učvrsti mjesec i sunce;"},{"v":17,"t":"ti sazda sve granice zemlji, ti stvori ljeto i zimu."},{"v":18,"t":"Spomeni se ovoga: dušmanin ti se rugaše, Jahve, i bezumni narod pogrdi ime tvoje."},{"v":19,"t":"Ne predaj jastrebu život grlice svoje, i život svojih siromaha ne zaboravi zauvijek!"},{"v":20,"t":"Pogledaj na Savez svoj, jer svi su zakuci zemlje puni tmina i nasilja."},{"v":21,"t":"Ne daj da jadnik otiđe postiđen: neka siromah i ubog hvale ime tvoje!"},{"v":22,"t":"Ustani, Bože, zauzmi se za svoju parnicu, spomeni se pogrde koju ti bezumnik svaki dan nanosi."},{"v":23,"t":"Ne zaboravi vike neprijatelja svojih: buka buntovnika još se diže k tebi!"}]},"75":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Ne razori!” Psalam. Asafov. Pjesma."},{"v":2,"t":"Slavimo te, Bože, slavimo i zazivamo ime tvoje, pripovijedamo čudesa tvoja."},{"v":3,"t":"“Kad odredim vrijeme, sudit ću po pravu."},{"v":4,"t":"Pa neka se strese zemlja sa stanovnicima svojim, ja sam učvrstio stupove njezine.”"},{"v":5,"t":"Drznike opominjem: “Ne budite drski!” bezbožnike: “Ne budite tako rogati!”"},{"v":6,"t":"Ne dižite roga svog protiv Neba, nemojte govoriti drsko na Boga!"},{"v":7,"t":"Jer niti sa istoka niti sa zapada, niti iz pustinje niti sa bregova ..."},{"v":8,"t":"Bog je koji sudi: ovoga snizuje, onog uzvisuje!"},{"v":9,"t":"Jer je u Jahvinoj ruci pehar pun vina pjenušava, začinjena mirisnim travama; iz njega on napaja, do taloga će ga iskapiti i ispiti svi zlotvori svijeta."},{"v":10,"t":"A ja ću klicati dovijeka, pjevat ću Bogu Jakovljevu."},{"v":11,"t":"Rogove ću polomiti bezbožniku, a pravednik će podići glavu."}]},"76":{"hr":[{"v":1,"t":"Zborovođi. Uza žičana glazbala. Psalam. Asafov. Pjesma."},{"v":2,"t":"Na glasu je Bog u Judeji, u Izraelu veliko je ime njegovo!"},{"v":3,"t":"U Šalemu je Šator njegov, na Sionu boravište."},{"v":4,"t":"Tu polomi strijele lukovima, štitove, mačeve, sve oružje."},{"v":5,"t":"Blistav si od svjetla, veličanstveniji od bregova drevnih."},{"v":6,"t":"Opljačkani su oni koji bijahu jaki srcem, i san svoj snivaju - klonuše ruke svim hrabrima."},{"v":7,"t":"Od prijetnje tvoje, Bože Jakovljev, skameniše se kola i konji."},{"v":8,"t":"Strašan si ti, i tko da opstane kraj žestine gnjeva tvojega."},{"v":9,"t":"S neba reče presudu - od straha zemlja zadrhta i zanijemje"},{"v":10,"t":"kad se diže Bog da sudi, da spasi uboge na zemlji."},{"v":11,"t":"Jer će te i bijes Edoma slaviti, i preživjeli iz Hamata štovat će te."},{"v":12,"t":"Zavjetujte i izvršite zavjete Jahvi, Bogu svojemu, svi oko njega neka donose darove Strašnome"},{"v":13,"t":"koji obuzdava oholost knezova, koji je strašan kraljevima zemlje."}]},"77":{"hr":[{"v":1,"t":"Zborovođi. Po Jedutunu. Asafov. Psalam."},{"v":2,"t":"Glasom svojim Bogu vapijem, glas mi se Bogu diže i on me čuje."},{"v":3,"t":"U dan nevolje tražim Gospodina, noću mi se ruka neumorno pruža k njemu, ne može se utješit' duša moja."},{"v":4,"t":"Spominjem se Boga i uzdišem; kad razmišljam, daha mi nestane."},{"v":5,"t":"Vjeđe moje držiš, potresen sam, ne mogu govoriti."},{"v":6,"t":"Mislim na drevne dane i sjećam se davnih godina;"},{"v":7,"t":"razmišljam noću u srcu, mislim, i duh moj ispituje:"},{"v":8,"t":"“Hoće li Gospodin odbaciti zauvijek i hoće li ikad još biti milostiv?"},{"v":9,"t":"Je li njegova dobrota minula zauvijek, njegovo obećanje propalo za sva pokoljenja?"},{"v":10,"t":"Zar Bog je zaboravio da se smiluje, ili je gnjevan zatvorio smilovanje svoje?”"},{"v":11,"t":"I govorim: “Ovo je bol moja: promijenila se desnica Višnjega.”"},{"v":12,"t":"Spominjem se djela Jahvinih, sjećam se tvojih pradavnih čudesa."},{"v":13,"t":"Promatram sva djela tvoja, razmatram ono što si učinio."},{"v":14,"t":"Svet je tvoj put, o Bože: koji je bog tako velik kao Bog naš?"},{"v":15,"t":"Ti si Bog koji čudesa stvaraš, na pucima si pokazao silu svoju."},{"v":16,"t":"Mišicom si izbavio narod svoj, sinove Jakovljeve i Josipove."},{"v":17,"t":"Vode te ugledaše, Bože, ugledaše te vode i ustuknuše, bezdani se uzburkaše."},{"v":18,"t":"Oblaci prosuše vode, oblaci zatutnjiše gromom i tvoje strijele poletješe."},{"v":19,"t":"Grmljavina tvoja u vihoru zaori, munje rasvijetliše krug zemaljski, zemlja se zatrese i zadrhta."},{"v":20,"t":"Kroz more put se otvori tebi i tvoja staza kroz vode goleme, a tragova tvojih nitko ne vidje."},{"v":21,"t":"Ti si svoj narod vodio kao stado rukama Mojsija i Arona."}]},"78":{"hr":[{"v":1,"t":"Poučna pjesma. Asafova. Poslušaj, narode moj, moju nauku, prikloni uho riječima usta mojih!"},{"v":2,"t":"Otvorit ću svoja usta na pouku, iznijet ću tajne iz vremena davnih."},{"v":3,"t":"Ono što čusmo i saznasmo, što nam kazivahu oci,"},{"v":4,"t":"nećemo kriti djeci njihovoj, predat ćemo budućem koljenu: slavu Jahvinu i silu njegovu i djela čudesna što ih učini."},{"v":5,"t":"Svjedočanstvo podiže on u Jakovu, Zakon postavi u Izraelu, da ono što naredi ocima našim oni djeci svojoj objave,"},{"v":6,"t":"da sazna budući naraštaj, i sinovi koji će se roditi da djeci svojoj kazuju"},{"v":7,"t":"da u Boga ufanje svoje stave i ne zaborave djela Božjih, već da vrše zapovijedi njegove,"},{"v":8,"t":"kako ne bi bili, kao oci njihovi, naraštaj buntovan, prkosan - naraštaj srcem nestalan i duhom Bogu nevjeran."},{"v":9,"t":"Sinovi Efrajimovi, ratnici s lukom, u dan bitke okrenuše leđa."},{"v":10,"t":"Saveza s Bogom ne održaše i ne htjedoše hoditi po Zakonu njegovu."},{"v":11,"t":"Zaboraviše na djela njegova, na čudesa koja im pokaza."},{"v":12,"t":"Pred njihovim ocima činio je znakove u Egiptu, u Soanskom polju."},{"v":13,"t":"On more razdijeli i njih prevede, vode kao nasip uzdiže."},{"v":14,"t":"Danju ih vodio oblakom, a svu noć ognjem blistavim."},{"v":15,"t":"U pustinji hrid prolomi i napoji ih obilno kao iz bezdana."},{"v":16,"t":"Iz stijene izbi potoke te izvede vode k'o velike rijeke."},{"v":17,"t":"A oni jednako griješiše, prkosiše Višnjem u pustinji."},{"v":18,"t":"Boga su kušali u srcima svojim ištuć' jela svojoj pohlepnosti."},{"v":19,"t":"Prigovarali su Bogu i pitali: “Može li Gospod stol u pustinji prostrti?"},{"v":20,"t":"Eno, udari u hrid, i voda poteče i provreše potoci: a može li dati i kruha, i mesa pružiti svome narodu?”"},{"v":21,"t":"Kad to začu Jahve, gnjevom usplamtje: oganj se raspali protiv Jakova, srdžba se razjari protiv Izraela,"},{"v":22,"t":"jer ne vjerovaše Bogu niti se u njegovu pomoć uzdaše."},{"v":23,"t":"Pa ozgo naredi oblaku i otvori brane nebeske,"},{"v":24,"t":"k'o kišu prosu na njih mÓanu da jedu i nahrani ih kruhom nebeskim."},{"v":25,"t":"Čovjek blagovaše kruh Jakih; on im dade hrane do sitosti."},{"v":26,"t":"Probudi na nebu vjetar istočni i svojom silom južnjak dovede."},{"v":27,"t":"Prosu na njih mesa k'o prašine i ptice krilatice k'o pijeska morskoga."},{"v":28,"t":"Padoše usred njihova tabora i oko šatora njihovih."},{"v":29,"t":"Jeli su i nasitili se, želju njihovu on im ispuni."},{"v":30,"t":"Još nisu svoju utažili pohlepu i jelo im još bješe u ustima,"},{"v":31,"t":"kad se srdžba Božja na njih raspali: pokosi smrću prvake njihove i mladiće pobi Izraelove."},{"v":32,"t":"Uza sve to griješiše dalje i ne vjerovaše u čudesna djela njegova."},{"v":33,"t":"I skonča im dane jednim dahom i njihova ljeta naglim svršetkom."},{"v":34,"t":"Kad ih ubijaše, tražiše ga i opet pitahu za Boga;"},{"v":35,"t":"spominjahu se da je Bog hridina njihova i Svevišnji njihov otkupitelj."},{"v":36,"t":"Ali ga opet ustima svojim varahu i jezikom svojim lagahu njemu."},{"v":37,"t":"Njihovo srce s njime ne bijaše, nit' bijahu vjerni Savezu njegovu."},{"v":38,"t":"A on im milosrdno grijeh praštao i nije ih posmicao; često je gnjev svoj susprezao da ne plane svom jarošću."},{"v":39,"t":"Spominjao se da su pÓut i dah koji odlazi i ne vraća se više."},{"v":40,"t":"Koliko mu prkosiše u pustinji i žalostiše ga u samotnom kraju!"},{"v":41,"t":"Sve nanovo iskušavahu Boga i vrijeđahu Sveca Izraelova"},{"v":42,"t":"ne spominjuć' se ruke njegove ni dana kad ih od dušmana izbavi,"},{"v":43,"t":"ni znakova njegovih u Egiptu, ni čudesnih djela u polju Soanskom."},{"v":44,"t":"U krv im pretvori rijeke i potoke, da ne piju."},{"v":45,"t":"Posla na njih obade da ih žderu i žabe da ih more."},{"v":46,"t":"I predade skakavcu žetvu njihovu, i plod muke njihove žderaču."},{"v":47,"t":"Vinograde im tučom udari, a mrazom smokvike njihove."},{"v":48,"t":"I predade grÓadu njihova goveda i munjama stada njihova."},{"v":49,"t":"Obori na njih svu žestinu gnjeva svog, jarost, bijes i nevolju: posla na njih anđele nesreće."},{"v":50,"t":"I put gnjevu svojem otvori: ne poštedje im život od smrti, životinje im izruči pošasti."},{"v":51,"t":"Pobi u Egiptu sve prvorođeno, prvence u šatorju Hamovu."},{"v":52,"t":"I povede narod svoj kao ovce i vođaše ih kao stado kroz pustinju."},{"v":53,"t":"Pouzdano ih je vodio te se nisu bojali, a more je prekrilo dušmane njihove."},{"v":54,"t":"U Svetu zemlju svoju on ih odvede, na bregove što mu ih osvoji desnica."},{"v":55,"t":"Pred njima istjera pogane, konopom im podijeli baštinu, pod šatorjem njihovim naseli plemena izraelska."},{"v":56,"t":"A oni iskušavali i gnjevili Boga Višnjega i nisu držali zapovijedi njegovih."},{"v":57,"t":"Otpadoše, iznevjeriše se k'o oci njihovi, k'o luk nepouzdan oni zatajiše."},{"v":58,"t":"Na gnjev ga nagnaše svojim uzvišicama, na ljubomor navedoše kumirima svojim."},{"v":59,"t":"Bog vidje i gnjevom planu, odbaci posve Izraela."},{"v":60,"t":"I napusti boravište svoje u Šilu, Šator u kojem prebivaše s ljudima."},{"v":61,"t":"Preda u ropstvo snagu svoju i svoju diku u ruke dušmanske."},{"v":62,"t":"Narod svoj prepusti maču, raspali se na svoju baštinu."},{"v":63,"t":"Mladiće njihove oganj proguta, ne udaše se djevice njihove."},{"v":64,"t":"Svećenici njihovi padoše od mača, ne zaplakaše Óudove njihove."},{"v":65,"t":"Tad se k'o oda sna trgnu Gospodin, k'o ratnik vinom savladan."},{"v":66,"t":"Udari otraga dušmane svoje, sramotu im vječitu zadade."},{"v":67,"t":"On odbaci šator Josipov i Efrajimovo pleme ne odabra,"},{"v":68,"t":"već odabra pleme Judino i goru Sion koja mu omilje."},{"v":69,"t":"Sagradi Svetište k'o nebo visoko, k'o zemlju utemelji ga dovijeka."},{"v":70,"t":"Izabra Davida, slugu svojega, uze ga od torova ovčjih;"},{"v":71,"t":"odvede ga od ovaca dojilica da pase Jakova, narod njegov, Izraela, baštinu njegovu."},{"v":72,"t":"I pasao ih je srcem čestitim i brižljivim rukama vodio."}]},"79":{"hr":[{"v":1,"t":"Psalam. Asafov. Bože, pogani, evo, provališe u baštinu tvoju, tvoj sveti Hram oskvrnuše, pretvoriše Jeruzalem u ruševine."},{"v":2,"t":"Trupla tvojih slugu dadoše za hranu pticama nebeskim, meso tvojih pobožnika zvijerima zemaljskim."},{"v":3,"t":"Krv im k'o vodu prolijevahu oko Jeruzalema i ne bijaše nikoga da ih pokopa."},{"v":4,"t":"Postadosmo sramota susjedima svojim, podsmijeh i ruglo svima oko nas."},{"v":5,"t":"Dokle još, Jahve? Zar ćeš se svagda srditi? Zar će ljubomora tvoja poput ognja gorjeti?"},{"v":6,"t":"Izlij gnjev na pogane koji te ne priznaju i na kraljevstva što ne zazivlju ime tvoje!"},{"v":7,"t":"Jer izjedoše Jakova i opustošiše boravište njegovo."},{"v":8,"t":"Ne spominji se, protiv nas, grijeha otaca; neka nas pretekne smilovanje tvoje jer smo jadni i nevoljni."},{"v":9,"t":"Pomozi nam, Bože, pomoći naša, zbog slave imena svojega, oslobodi nas i otpusti nam grijehe zbog imena svoga!"},{"v":10,"t":"Zašto da pogani govore: “TÓa gdje je njihov Bog?” Nek' se na poganima pokaže, pred očima našim, kako osvećuješ prolivenu krv slugu svojih!"},{"v":11,"t":"Nek' do tebe dopru uzdasi sužanja, snagom svoje mišice poštedi predane smrti!"},{"v":12,"t":"A našim susjedima vrati sedmerostruko u krilo pogrdu koju naniješe tebi, o Jahve!"},{"v":13,"t":"A mi, tvoj puk i ovce paše tvoje, slavit ćemo te dovijeka, kazivat ćemo od koljena do koljena hvalu tvoju!"}]},"80":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Ljiljan svjedočanstva”. Asafov. Psalam."},{"v":2,"t":"Pastiru Izraelov, počuj, ti što vodiš Josipa k'o stado ovaca! Ti što sjediš nad kerubima, zablistaj"},{"v":3,"t":"pred Efrajimom, Benjaminom, Manašeom: probudi silu svoju, priteci nam u pomoć!"},{"v":4,"t":"Bože, obnovi nas, razvedri lice svoje i spasi nas!"},{"v":5,"t":"Jahve, Bože nad Vojskama, dokle ćeš plamtjeti, premda se moli narod tvoj?"},{"v":6,"t":"Dokle ćeš nas hraniti kruhom suza i obilno pojiti suzama?"},{"v":7,"t":"Dokle će se oko nas svađat' susjedi i rugat' nam se naši dušmani?"},{"v":8,"t":"Bože nad Vojskama, obnovi nas, razvedri lice svoje i spasi nas!"},{"v":9,"t":"Ti prenese čokot iz Egipta, pogane istjera, a njega zasadi."},{"v":10,"t":"Ti mu tlo pripravi, i on pusti korijenje i napuni zemlju."},{"v":11,"t":"Sjena mu prekri bregove, lozje mu k'o Božji cedrovi."},{"v":12,"t":"Mladice svoje ispruži do mora i svoje ogranke do Rijeke."},{"v":13,"t":"Zašto si mu srušio ogradu da ga beru svi što putem prolaze,"},{"v":14,"t":"da ga pustoši vepar iz šume, da ga pasu poljske zvijeri?"},{"v":15,"t":"Vrati se, Bože nad Vojskama, pogledaj s neba i vidi, obiđi ovaj vinograd:"},{"v":16,"t":"zakrili što zasadi desnica tvoja, sina kog za se odgoji!"},{"v":17,"t":"Oni koji ga spališe i posjekoše nek' izginu od prijetnje lica tvojega!"},{"v":18,"t":"Tvoja ruka nek' bude nad čovjekom desnice tvoje, nad sinom čovječjim kog za se odgoji!"},{"v":19,"t":"Nećemo se više odmetnuti od tebe; poživi nas, a mi ćemo zazivati ime tvoje."},{"v":20,"t":"Jahve, Bože nad Vojskama, obnovi nas, razvedri lice svoje i spasi nas!"}]},"81":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Tijesci”. Asafov."},{"v":2,"t":"Kliknite Bogu, našoj jakosti, kličite Bogu Jakovljevu!"},{"v":3,"t":"Nek' zazvuče žice, nek' se čuje bubanj, svirajte u milozvučnu harfu s citarom!"},{"v":4,"t":"Zatrubite u rog za mlađaka, za uštapa, na svetkovinu našu!"},{"v":5,"t":"Jer to je propis Izraelu, zapovijed Boga Jakovljeva."},{"v":6,"t":"Takav je zakon dao Josipu kad je izlazio iz zemlje Egipta."},{"v":7,"t":"Šapat tajnovit čuh: “Oslobodih od tereta rame njegovo, ruke su mu slobodne od košare."},{"v":8,"t":"U tjeskobi si zavapio i ja te izbavih; iz gromovna oblaka odgovorih tebi, iskušah te kod voda meripskih."},{"v":9,"t":"Slušaj, puče moj, i ja ću te opomenuti: o, da me poslušaš, Izraele!"},{"v":10,"t":"Nek' ne bude u tebe drugog boga i ne klanjaj se bogu tuđem!"},{"v":11,"t":"Ja sam Jahve, Bog tvoj koji te izvedoh iz Egipta: otvori svoja usta da ih napunim!”"},{"v":12,"t":"“Ali moj narod ne slušaše glasa moga, Izrael me ne posluša."},{"v":13,"t":"Zato ga pustih okorjelom srcu njegovu: neka hodi kako mu se hoće!"},{"v":14,"t":"O, kad bi me narod moj slušao, kad bi Izrael putovima mojim hodio,"},{"v":15,"t":"brzo bih pokorio dušmane njegove, ruku bih svoju okrenuo na protivnike njegove."},{"v":16,"t":"Oni što ga sada mrze dodvarali bi mu se i njihov bi udes bio zapečaćen zauvijek."},{"v":17,"t":"A svoj narod hranio bih pšenicom najboljom i sitio ga medom iz pećine."}]},"82":{"hr":[{"v":1,"t":"Psalam. Asafov. Bog ustaje u skupštini “bogova”, usred “bogova” sud održava."},{"v":2,"t":"“Dokle ćete sudit' krivo, ić' na ruku bezbožnima?"},{"v":3,"t":"Štitite slaba i sirotu, vratite pravicu jadniku i siromahu!"},{"v":4,"t":"Izbavite potlačenog i ubogog: istrgnite ga iz ruku bezbožnih!”"},{"v":5,"t":"Ne shvaćaju nit' razumiju, po mraku hodaju: poljuljani su svi temelji zemlje."},{"v":6,"t":"Rekoh doduše: “Vi ste bogovi i svi ste sinovi Višnjega!"},{"v":7,"t":"Ali ćete k'o svi ljudi umrijeti, past ćete kao svatko od velikih!”"},{"v":8,"t":"Ustani, Bože, i sudi zemlju, jer si s pravom gospodar svih naroda."}]},"83":{"hr":[{"v":1,"t":"Pjesma. Psalam. Asafov."},{"v":2,"t":"Ne šuti, Jahve, ne budi nijem i nemoj mirovati, Bože!"},{"v":3,"t":"Jer evo: dušmani tvoji buče, i mrzitelji tvoji glave podižu."},{"v":4,"t":"Protiv naroda se tvoga rote i svjetuju se protiv štićenika tvojih."},{"v":5,"t":"Govore: “Dođite, zatrimo ih da ne budu narod, nek' se ime Izrael više ne spominje!”"},{"v":6,"t":"Zaista, jednodušno se svjetuju i protiv tebe savez sklopiše:"},{"v":7,"t":"šatori edomski i Jišmaelci, Moapci i Hagrijci,"},{"v":8,"t":"Gebal i Amon i Amalek, Filisteja sa stanovnicima Tira."},{"v":9,"t":"I Asirci se s njima udružiše, pružiše ruke potomcima Lotovim."},{"v":10,"t":"Učini njima k'o Midjancima, k'o Siseri i Jabinu na potoku Kišonu:"},{"v":11,"t":"koji padoše blizu En-Dora i postaše gnojivo njivi."},{"v":12,"t":"K'o Oreb i Zeb neka budu knezovi njihovi, kao Zebah i Salmuna nek' budu sve vođe njihove"},{"v":13,"t":"koji jednodušno vikahu: “Osvojimo krajeve Božje!”"},{"v":14,"t":"Daj, o Bože, da budu kao kovitlac, kao pljeva koju nosi vjetar."},{"v":15,"t":"Kao što oganj proždire šumu, kao što plamen sažiže bregove,"},{"v":16,"t":"tako ih goni olujom svojom, prestravi ih svojom žestinom!"},{"v":17,"t":"Pokrij im lice sramotom, da traže tvoje ime, Jahve!"},{"v":18,"t":"Neka se stide i plaše navijek, neka se posrame i neka izginu!"},{"v":19,"t":"Nek' znaju: ti si komu je ime Jahve, jedini Višnji nada svom zemljom."}]},"84":{"hr":[{"v":1,"t":"Zborovođi. Po napjevu “Tijesci”. Sinova Korahovih."},{"v":2,"t":"Kako su mili stanovi tvoji, Jahve nad Vojskama!"},{"v":3,"t":"Duša mi gine i čezne za dvorima Jahvinim. Srce moje i moje tijelo kliču Bogu živomu."},{"v":4,"t":"I vrabac sebi log nalazi, i lastavica gnjezdašce gdje će položiti mlade svoje:"},{"v":5,"t":"a ja žrtvenike tvoje, Jahve nad Vojskama, Kralju moj i Bože moj! Blaženi koji prebivaju u Domu tvome slaveć' te bez prestanka!"},{"v":6,"t":"Blažen komu je pomoć u tebi dok se sprema na svete putove!"},{"v":7,"t":"Prolaze li suhom dolinom, u izvor je vode promeću i prva je kiša u blagoslov odijeva."},{"v":8,"t":"Snaga im raste od časa do časa: dok ne ugledaju Boga na Sionu."},{"v":9,"t":"Jahve, Bože nad Vojskama, čuj molitvu moju, poslušaj, Bože Jakovljev!"},{"v":10,"t":"Pogledaj, štite naš, Bože, pogledaj lice pomazanika svoga!"},{"v":11,"t":"Zaista, jedan je dan u dvorima tvojim bolji od tisuću drugih. Volim biti na pragu Doma Boga svoga nego boraviti u šatorima grešnika."},{"v":12,"t":"Jahve, Bog, sunce je i štit: on daje milost i slavu. Ne uskraćuje Jahve dobara onima koji idu u nedužnosti."},{"v":13,"t":"Jahve nad Vojskama, blago onom tko se u te uzda."}]},"85":{"hr":[{"v":1,"t":"Zborovođi. Sinova Korahovih. Psalam."},{"v":2,"t":"Zavolje opet, Jahve, zemlju svoju, na dobro okrenu udes Jakovljev."},{"v":3,"t":"Otpusti krivnju narodu svome, pokri sve grijehe njegove."},{"v":4,"t":"Suspregnu svu ljutinu svoju, odusta od žestine gnjeva svoga."},{"v":5,"t":"Obnovi nas, Bože, Spasitelju naš, i odbaci zlovolju prema nama!"},{"v":6,"t":"Zar ćeš se dovijeka gnjeviti na nas, prenositi srdžbu svoju od koljena na koljeno?"},{"v":7,"t":"Zar nas nećeš opet oživiti da se narod tvoj raduje u tebi?"},{"v":8,"t":"Pokaži nam, Jahve, milosrđe svoje i daj nam svoje spasenje."},{"v":9,"t":"Da poslušam što mi to Jahve govori: Jahve obećava mir narodu svomu, vjernima svojim, onima koji mu se svim srcem vrate."},{"v":10,"t":"Zaista, blizu je njegovo spasenje onima koji ga se boje, i slava će njegova živjeti u zemlji našoj."},{"v":11,"t":"Ljubav će se i Vjernost sastati, Pravda i Mir zagrliti."},{"v":12,"t":"Vjernost će nicat' iz zemlje, Pravda će gledat' s nebesa."},{"v":13,"t":"Jahve će dati blagoslov i sreću, i zemlja naša urod svoj."},{"v":14,"t":"Pravda će stupati pred njim, a Mir tragom stopa njegovih."}]},"86":{"hr":[{"v":1,"t":"Molitva. Davidova. Prigni uho svoje, Jahve, i usliši me jer sam bijedan i ubog."},{"v":2,"t":"Čuvaj dušu moju jer sam posvećen tebi; spasi slugu svoga koji se uzda u te! Ti si moj Bog;"},{"v":3,"t":"o Gospode, smiluj mi se jer povazdan vapijem k tebi."},{"v":4,"t":"Razveseli dušu sluge svoga jer k tebi, Jahve, dušu uzdižem."},{"v":5,"t":"Jer ti si, Gospode, dobar i rado praštaš, pun si ljubavi prema svima koji te zazivaju."},{"v":6,"t":"Slušaj, Jahve, molitvu moju i pazi na glas vapaja mog."},{"v":7,"t":"U dan tjeskobe vapijem k tebi jer ćeš me uslišati."},{"v":8,"t":"Nema ti ravna među bozima, Gospode, nema djela kakvo je tvoje."},{"v":9,"t":"Svi narodi što ih stvori doći će i klanjat' se tebi, o Jahve, i slavit će ime tvoje."},{"v":10,"t":"Jer ti si velik i činiš čudesa: ti si jedini Bog."},{"v":11,"t":"Uči me, Jahve, svojemu putu da hodim vjeran tebi, usmjeri srce moje da se boji imena tvojega!"},{"v":12,"t":"Hvalit ću te, Gospode, Bože moj, svim srcem svojim, slavit ću ime tvoje dovijeka,"},{"v":13,"t":"jer tvoje ljubavi prema meni ima izobila, istrgao si moju dušu iz dubine Podzemlja."},{"v":14,"t":"O Bože, oholice se digoše na me, mnoštvo silnika život mi vreba i nemaju tebe pred očima."},{"v":15,"t":"No ti si, Gospode Bože, milosrdan i blag, spor na srdžbu - sama ljubav i vjernost."},{"v":16,"t":"Pogledaj na me i smiluj se meni; daj svome sluzi snage svoje i spasi sina sluškinje svoje!"},{"v":17,"t":"Daj mi milostivo znak naklonosti svoje, da vide moji mrzitelji i da se postide, jer si mi ti, o Jahve, pomogao, ti me utješio."}]},"87":{"hr":[{"v":1,"t":"Sinova Korahovih. Psalam. Pjesma. Zdanje svoje na svetim gorama"},{"v":2,"t":"ljubi Jahve; draža su mu vrata sionska nego svi šatori Jakovljevi."},{"v":3,"t":"Divote se govore o tebi, grade Božji!"},{"v":4,"t":"“Rahab i Babilon brojit ću k onima što me štuju; Filisteja i Tir i narod etiopski - i oni su rođeni ondje.”"},{"v":5,"t":"O Sionu se govori: “Ovaj i onaj u njemu je rođen! Svevišnji ga utemelji!”"},{"v":6,"t":"Gospodin će zapisati u knjigu naroda: “Ovi su rođeni ondje.”"},{"v":7,"t":"I pjevat će igrajući kolo: “Svi su izvori moji u tebi!”"}]},"88":{"hr":[{"v":1,"t":"Pjesma. Psalam. Sinova Korahovih. Zborovođi. Po napjevu “Bolest”. Za pjevanje. Poučna pjesma. Ezrahijca Hemana."},{"v":2,"t":"Jahve, Bože moj, vapijem danju, a noću naričem pred tobom."},{"v":3,"t":"Neka dopre do tebe molitva moja, prigni uho k vapaju mome."},{"v":4,"t":"Jer mi je duša zasićena patnjama, moj se život bliži Podzemlju."},{"v":5,"t":"Broje me k onima što u grob silaze, postadoh sličan nemoćniku."},{"v":6,"t":"Među mrtvima moj je ležaj, poput ubijenih što leže u grobu kojih se više ne spominješ, od kojih si ustegao ruku."},{"v":7,"t":"Smjestio si me u jamu duboku, u tmine, u bezdan."},{"v":8,"t":"Teško me pritišće ljutnja tvoja i svim me valima svojim prekrivaš."},{"v":9,"t":"Udaljio si od mene znance moje, Óučini da im gnusan budem: zatvoren sam, ne mogu izaći."},{"v":10,"t":"Od nevolje oči mi gasnu: vapijem tebi, Jahve, iz dana u dan, za tobom ruke pružam."},{"v":11,"t":"Zar na mrtvima činiš čudesa? Zar će sjene ustati i hvaliti tebe?"},{"v":12,"t":"Zar se u grobu pripovijeda o tvojoj dobroti? O vjernosti tvojoj u Propasti?"},{"v":13,"t":"Zar se u tmini objavljuju čudesa tvoja i tvoja pravda u Zaboravu?"},{"v":14,"t":"Ipak ja vapijem tebi, Jahve, prije jutra molitvom te pretječem."},{"v":15,"t":"Zašto, Jahve, odbacuješ dušu moju? Zašto sakrivaš lice od mene?"},{"v":16,"t":"Bijedan sam i umirem već od dječaštva, klonuh noseći tvoje strahote."},{"v":17,"t":"Preko mene prijeđoše vihori tvojega gnjeva, strahote me tvoje shrvaše,"},{"v":18,"t":"okružuju me kao voda sveudilj, optječu me svi zajedno."},{"v":19,"t":"Udaljio si od mene prijatelja i druga: mrak mi je znanac jedini."}]},"89":{"hr":[{"v":1,"t":"Poučna pjesma. Ezrahijca Etana."},{"v":2,"t":"O ljubavi Jahvinoj pjevat ću dovijeka, kroza sva koljena vjernost ću tvoju naviještati."},{"v":3,"t":"Ti reče: “Zavijeke je sazdana ljubav moja!” U nebu utemelji vjernost svoju:"},{"v":4,"t":"“Savez sklopih s izabranikom svojim, zakleh se Davidu, sluzi svome:"},{"v":5,"t":"tvoje potomstvo održat ću dovijeka, za sva koljena sazdat ću prijestolje tvoje.”"},{"v":6,"t":"Nebesa veličaju čudesa tvoja, Jahve, i tvoju vjernost u zboru svetih."},{"v":7,"t":"TÓa tko je u oblacima ravan Jahvi, tko li je Jahvi sličan među sinovima Božjim?"},{"v":8,"t":"Bog je strahovit u zboru svetih, velik i strašan svima oko sebe."},{"v":9,"t":"Jahve, Bože nad Vojskama, tko je kao ti? Silan si, Jahve, i vjernost te okružuje."},{"v":10,"t":"Ti zapovijedaš bučnome moru, obuzdavaš silu valova njegovih;"},{"v":11,"t":"ti sasječe Rahaba i zgazi, snažnom mišicom rasu dušmane svoje."},{"v":12,"t":"Tvoja su nebesa i tvoja je zemlja, zemljin krug ti si sazdao i sve što je na njemu;"},{"v":13,"t":"sjever i jug ti si stvorio, Tabor i Hermon kliču imenu tvojemu."},{"v":14,"t":"Tvoja je mišica snažna, ruka čvrsta, desnica dignuta."},{"v":15,"t":"Pravda i Pravednost temelj su prijestolja tvoga, Ljubav i Istina koračaju pred tobom."},{"v":16,"t":"Blago narodu vičnu svetom klicanju, on hodi u sjaju lica tvojega, Jahve,"},{"v":17,"t":"u tvom se imenu raduje svagda i tvojom se pravdom ponosi."},{"v":18,"t":"Jer ti si ures moći njegove, po tvojoj milosti raste snaga naša."},{"v":19,"t":"Jer Jahve je štit naš, Svetac Izraelov kralj je naš."},{"v":20,"t":"Nekoć si u viđenju govorio pobožnima svojim: “Junaku stavih krunu na glavu, izabranika iz naroda izdigoh;"},{"v":21,"t":"nađoh Davida, slugu svoga, svetim ga svojim uljem pomazah,"},{"v":22,"t":"da ruka moja svagda ostane s njime i moja mišica da ga krijepi."},{"v":23,"t":"Neće ga nadmudriti dušmanin, niti oboriti sin bezakonja."},{"v":24,"t":"Razbit ću pred njim protivnike njegove, pogubit ću mrzitelje njegove."},{"v":25,"t":"Vjernost moja i dobrota bit će s njime i u mome imenu rast će mu snaga."},{"v":26,"t":"Pružit ću njegovu ruku nad more, do Rijeke desnicu njegovu."},{"v":27,"t":"On će me zvati: 'Oče moj! Bože moj i hridi spasa mojega.'"},{"v":28,"t":"A ja ću ga prvorođencem učiniti, najvišim među kraljevima svijeta."},{"v":29,"t":"Njemu ću sačuvati dovijeka naklonost svoju i Savez svoj vjeran."},{"v":30,"t":"Njegovo ću potomstvo učiniti vječnim i prijestolje mu kao dan nebeski."},{"v":31,"t":"Ako li mu sinovi Zakon moj ostave i ne budu hodili po naredbama mojim,"},{"v":32,"t":"ako li prestupe odredbe moje i ne budu čuvali zapovijedi mojih;"},{"v":33,"t":"šibom ću kazniti nedjelo njihovo, udarcima ljutim krivicu njihovu,"},{"v":34,"t":"ali mu naklonosti svoje oduzeti neću niti ću prekršiti vjernosti svoje."},{"v":35,"t":"Neću povrijediti Saveza svojega i neću poreći obećanja svoga."},{"v":36,"t":"Jednom se zakleh svetošću svojom: Davida prevariti neću:"},{"v":37,"t":"potomstvo će njegovo ostati dovijeka, prijestolje njegovo preda mnom kao sunce,"},{"v":38,"t":"ostat će dovijeka kao mjesec, vjerni svjedok na nebu.”"},{"v":39,"t":"A sada ti ga odbi i odbaci, silno se razgnjevi na pomazanika svoga."},{"v":40,"t":"Prezre Savez sa slugom svojim i krunu njegovu do zemlje ponizi."},{"v":41,"t":"Razvali sve zidine njegove, njegove utvrde u ruševine baci."},{"v":42,"t":"Pljačkaju ga svi što naiđu, na ruglo je susjedima svojim."},{"v":43,"t":"Podiže desnicu dušmana njegovih i obradova protivnike njegove."},{"v":44,"t":"Otupi oštricu mača njegova, u boju mu ne pomože."},{"v":45,"t":"Njegovu sjaju kraj učini, njegovo prijestolje na zemlju obori."},{"v":46,"t":"Skratio si dane mladosti njegove, sramotom ga pokrio."},{"v":47,"t":"TÓa dokle ćeš, Jahve? Zar ćeš se uvijek skrivati? Hoće li gnjev tvoj k'o oganj gorjeti?"},{"v":48,"t":"Sjeti se kako je kratak život moj, kako si ljude prolazne stvorio!"},{"v":49,"t":"Tko živ smrti vidjeti neće? Tko će od ruke Podzemlja dušu sačuvati?"},{"v":50,"t":"Gdje li je, Jahve, tvoja dobrota iskonska kojom se Davidu zakle na vjernost svoju?"},{"v":51,"t":"Sjeti se, Jahve, sramote slugu svojih: u srcu nosim svu mržnju pogana"},{"v":52,"t":"s kojom nasrću dušmani tvoji, Jahve, s kojom nasrću na korake pomazanika tvoga."},{"v":53,"t":"Blagoslovljen Jahve dovijeka! Tako neka bude. Amen!"}]},"90":{"hr":[{"v":1,"t":"Molitva. Mojsija, sluge Božjega. Jahve, ti nam bijaše okrilje od koljena do koljena."},{"v":2,"t":"Prije nego se rodiše bregovi, prije nego postade kopno i krug zemaljski, od vijeka do vijeka, Bože, ti jesi!"},{"v":3,"t":"Smrtnike u prah vraćaš i veliš: “Vratite se, sinovi ljudski!”"},{"v":4,"t":"Jer je tisuću godina u očima tvojim k'o jučerašnji dan koji je minuo i kao straža noćna."},{"v":5,"t":"Razgoniš ih k'o jutarnji san, kao trava su što se zeleni:"},{"v":6,"t":"jutrom cvate i sva se zeleni, a uvečer - već se suši i vene."},{"v":7,"t":"Zaista, izjeda nas tvoja srdžba i zbunjuje ljutina tvoja."},{"v":8,"t":"Naše si grijehe stavio pred svoje oči, naše potajne grijehe na svjetlost lica svojega."},{"v":9,"t":"Jer svi naši dani prođoše u gnjevu tvojemu, kao uzdah dovršismo godine svoje."},{"v":10,"t":"Zbroj naše dobi sedamdeset je godina, ako smo snažni, i osamdeset; a većina od njih muka je i ništavost: jer prolaze brzo i mi letimo odavle."},{"v":11,"t":"Tko će mjeriti žestinu gnjeva tvojega, tko proniknuti srdžbu tvoju?"},{"v":12,"t":"Nauči nas dane naše brojiti, da steknemo mudro srce."},{"v":13,"t":"Vrati se k nama, Jahve! TÓa dokle ćeš? Milostiv budi slugama svojim!"},{"v":14,"t":"Jutrom nas nasiti smilovanjem svojim, da kličemo i da se veselimo u sve dane!"},{"v":15,"t":"Obraduj nas za dane kad si nas šibao, za ljeta kad smo stradali!"},{"v":16,"t":"Neka se na slugama tvojim pokaže djelo tvoje i tvoja slava na djeci njihovoj!"},{"v":17,"t":"Dobrota Jahve, Boga našega, nek' bude nad nama daj da nam uspije djelo naših ruku, djelo ruku naših nek' uspije."}]},"91":{"hr":[{"v":1,"t":"Ti što prebivaš pod zaštitom Višnjega, što počivaš u sjeni Svemogućega,"},{"v":2,"t":"reci Jahvi: “Zaklone moj! Utvrdo moja! Bože moj u koga se uzdam!”"},{"v":3,"t":"Jer on će te osloboditi od zamke ptičarske, od kuge pogubne."},{"v":4,"t":"Svojim će te krilima zaštititi i pod njegova ćeš se krila skloniti: Vjernost je njegova štit i obrana!"},{"v":5,"t":"Nećeš se bojati strašila noćnoga ni strelice što leti danju,"},{"v":6,"t":"ni kuge što se šulja kroz tmine, ni pošasti što hara o podne."},{"v":7,"t":"Pa nek' padaju tisuće kraj tebe, deseci tisuća s desne tvoje, tebi se neće primaći!"},{"v":8,"t":"Tek što okom pogledaš, već ćeš vidjeti plaću grešnika."},{"v":9,"t":"Jer Jahve je zaklon tvoj, Višnjega odabra sebi za okrilje."},{"v":10,"t":"Neće te snaći nesreća, nevolja se neće prikučiti šatoru tvojemu."},{"v":11,"t":"Jer anđelima svojim zapovjedi da te čuvaju na svim putima tvojim."},{"v":12,"t":"Na rukama će te nositi da se ne spotakneš o kamen."},{"v":13,"t":"Nogom ćeš gaziti lava i ljuticu, zgazit ćeš lavića i zmiju."},{"v":14,"t":"Izbavit ću ga jer me ljubi, zakrilit ga jer poznaje ime moje."},{"v":15,"t":"Zazvat će me, a ja ću ga uslišiti, s njim ću biti u nevolji, spasit ću ga i proslaviti."},{"v":16,"t":"Nasitit ću ga danima mnogim, pokazat' mu spasenje svoje.”"}]},"92":{"hr":[{"v":1,"t":"Psalam. Pjesma. Za dan subotnji."},{"v":2,"t":"Dobro je slaviti Jahvu, pjevati imenu tvome, Svevišnji;"},{"v":3,"t":"naviještati jutrom ljubav tvoju i noću vjernost tvoju,"},{"v":4,"t":"uz harfu od deset žica i liru, s pjesmom uz citaru."},{"v":5,"t":"Obradovao si me djelima svojim, o Jahve, kličem zbog djela ruku tvojih."},{"v":6,"t":"Kako su silna djela tvoja, o Jahve, i duboki naumi tvoji!"},{"v":7,"t":"Bezuman čovjek ne spoznaje, luđak ne shvaća."},{"v":8,"t":"Sve ako bi bezbošci nicali k'o trava i cvali svi što zlo čine, određeni su za vječnu propast;"},{"v":9,"t":"a ti, Jahve, dovijeka uzvišen ostaješ."},{"v":10,"t":"Doista, dušmani tvoji, o Jahve, tvoji će dušmani propasti; raspršit će se svi što čine zlo."},{"v":11,"t":"Rog si mi digao k'o u bivola, pomazao me uljem prečistim;"},{"v":12,"t":"i oko mi s visoka gleda dušmane i uho mirno sluša o onima što na me ustaju."},{"v":13,"t":"K'o palma cvate pravednik i raste k'o cedar libanonski."},{"v":14,"t":"Zasađeni u Domu Jahvinu, cvatu u dvorima Boga našega."},{"v":15,"t":"Rod donose i u starosti, sočni i puni svježine:"},{"v":16,"t":"da navijeste kako je pravedan Jahve, Hrid moja, onaj na kome nema nepravde."}]},"93":{"hr":[{"v":1,"t":"Jahve kraljuje, u sjaj zaodjeven, Jahve zaodjeven moći i opasan. Čvrsto stoji krug zemaljski, neće se poljuljati."},{"v":2,"t":"Čvrsto je prijestolje tvoje odiskona, ti si od vječnosti!"},{"v":3,"t":"Rijeke podižu, Jahve, rijeke podižu glase svoje, rijeke podižu svoj bučni huk."},{"v":4,"t":"Jači od glasova voda golemih, silniji od bijesnoga mora: silan je Jahve u visinama."},{"v":5,"t":"Tvoja su obećanja vjere predostojna, svetost je ures Doma tvojega, Jahve, u sve dane!"}]},"94":{"hr":[{"v":1,"t":"Bože osvetniče, Jahve, Bože osvetniče, pokaži se."},{"v":2,"t":"Ustani ti što sudiš zemlju, po zasluzi plati oholima!"},{"v":3,"t":"Dokle će bezbošci, Jahve, dokle će se bezbošci hvastati?"},{"v":4,"t":"Dokle će brbljati, drsko govoriti, dokle će se bezakonici hvastati?"},{"v":5,"t":"Tlače narod tvoj, Jahve, i baštinu tvoju pritišću;"},{"v":6,"t":"kolju udovicu i pridošlicu, sirotama život oduzimlju"},{"v":7,"t":"i govore: “Jahve ne vidi! Ne opaža Bog Jakovljev!”"},{"v":8,"t":"Shvatite, lude u narodu: bezumni, kad ćete se urazumiti?"},{"v":9,"t":"Onaj što uho zasadi da ne čuje? Koji stvori oko da ne vidi?"},{"v":10,"t":"Onaj što odgaja narode da ne kazni - Onaj što ljude uči mudrosti?"},{"v":11,"t":"Jahve poznaje namisli ljudske: one su isprazne."},{"v":12,"t":"Blago onom koga ti poučavaš, Jahve, i učiš Zakonu svojemu:"},{"v":13,"t":"da mu mir udijeliš od nesretnih dana, dok se grob kopa zlikovcu."},{"v":14,"t":"Jer neće Jahve odbaciti naroda svojega i svoje baštine neće napustiti;"},{"v":15,"t":"jer će se pravo dosuditi pravednosti i za njom će ići svi čestiti srcem."},{"v":16,"t":"Tko će ustati za me protiv zlotvora? Tko će se zauzeti za me protiv zločinaca?"},{"v":17,"t":"Da mi Jahve ne pomaže, brzo bih sišao u mjesto tišine."},{"v":18,"t":"Čim pomislim: “Noga mi posrće”, dobrota me tvoja, o Jahve, podupire."},{"v":19,"t":"Kad se skupe tjeskobe u srcu mome, tvoje mi utjehe dušu vesele."},{"v":20,"t":"Zar je bezbožno sudište u savezu s tobom kad nevolje stvara pod izlikom zakona?"},{"v":21,"t":"Nek' samo pritišću dušu pravednog, nek' osuđuju krv nedužnu:"},{"v":22,"t":"Jahve mi je utvrda, Bog - hrid utočišta moga."},{"v":23,"t":"Platit će im bezakonje njihovo, njihovom će ih zloćom istrijebiti, istrijebit će ih Jahve, Bog naš."}]},"95":{"hr":[{"v":1,"t":"Dođite, kličimo Jahvi, uzvikujmo Hridi, Spasitelju svome!"},{"v":2,"t":"Pred lice mu stupimo s hvalama, kličimo mu u pjesmama!"},{"v":3,"t":"Jer velik je Jahve, Bog naš, Kralj veliki nad svim bogovima."},{"v":4,"t":"U njegovoj su ruci zemaljske dubine, njegovi su vrhunci planina."},{"v":5,"t":"Njegovo je more, on ga je stvorio, i kopno koje načiniše ruke njegove."},{"v":6,"t":"Dođite, prignimo koljena i padnimo nice, poklonimo se Jahvi koji nas stvori!"},{"v":7,"t":"Jer on je Bog naš, a mi narod paše njegove, ovce što on ih čuva. O, da danas glas mu poslušate:"},{"v":8,"t":"“Ne budite srca tvrda kao u Meribi, kao u dan Mase u pustinji"},{"v":9,"t":"gdje me iskušavahu očevi vaši premda vidješe djela moja."},{"v":10,"t":"Četrdeset ljeta jadio me naraštaj onaj, pa rekoh: 'Narod su nestalna srca i ne promiču moje putove.'"},{"v":11,"t":"Stog se zakleh u svom gnjevu: 'Nikad neće ući u moj pokoj!'”"}]},"96":{"hr":[{"v":1,"t":"Pjevajte Jahvi pjesmu novu! Pjevaj Jahvi, sva zemljo!"},{"v":2,"t":"Pjevajte Jahvi, hvalite ime njegovo! Navješćujte iz dana u dan spasenje njegovo,"},{"v":3,"t":"kazujte poganima njegovu slavu, svim narodima čudesa njegova."},{"v":4,"t":"Velik je Jahve, hvale predostojan, strašniji od svih bogova!"},{"v":5,"t":"Ništavni su svi bozi naroda. Jahve stvori nebesa!"},{"v":6,"t":"Slava je i veličanstvo pred njim, sila i sjaj u Svetištu njegovu."},{"v":7,"t":"Dajte Jahvi, narodna plemena, dajte Jahvi slavu i silu!"},{"v":8,"t":"Dajte Jahvi slavu imena njegova! Prinosite žrtvu i uđite u dvorove njegove,"},{"v":9,"t":"poklonite se Jahvi u sjaju svetosti njegove. Strepi pred njim, zemljo sva!"},{"v":10,"t":"Nek' se govori među poganima: “Jahve kraljuje!” Svijet on učvrsti da se ne pomakne, narodima pravedno upravlja."},{"v":11,"t":"Raduj se, nebo, i kliči, zemljo! Neka huči more i što je u njemu!"},{"v":12,"t":"Nek' se raduje polje i što je na njemu, neka klikće šumsko drveće"},{"v":13,"t":"pred Jahvom, jer dolazi, jer dolazi suditi zemlji. Sudit će svijetu u pravdi i narodima u istini svojoj."}]},"97":{"hr":[{"v":1,"t":"Jahve kraljuje: neka kliče zemlja, nek' se vesele otoci mnogi!"},{"v":2,"t":"Oblak i tama ovijaju njega, pravda i pravo temelji su prijestolja njegova."},{"v":3,"t":"Oganj ide pred njim i sažiže okolo dušmane njegove."},{"v":4,"t":"Munje mu svijet osvjetljuju; zemlja to vidi i strepi."},{"v":5,"t":"Brda se tope pred Jahvom k'o vosak, pred vladarom zemlje sve."},{"v":6,"t":"Nebesa navješćuju pravednost njegovu, svi narodi gledaju mu slavu."},{"v":7,"t":"Nek' se postide svi što likove štuju i koji se hvale kumirima. Poklonite mu se, svi bozi!"},{"v":8,"t":"Sion radostan sluša, gradovi Judini kliču zbog tvojih sudova, o Jahve!"},{"v":9,"t":"Jer ti si, o Jahve, Svevišnji - nad svom zemljom, visoko, visoko nad bozima svima."},{"v":10,"t":"Jahve ljubi one koji mrze na zlo, on čuva duše pobožnika svojih, izbavlja ih iz ruku opakih."},{"v":11,"t":"Svjetlost sviće pravedniku i radost čestitima u srcu."},{"v":12,"t":"Radujte se, pravednici, u Jahvi, slavite sveto ime njegovo!"}]},"98":{"hr":[{"v":1,"t":"Psalam. Pjevajte Jahvi pjesmu novu, jer učini djela čudesna. Pobjedu mu pribavi desnica njegova i sveta mišica njegova."},{"v":2,"t":"Jahve obznani spasenje svoje, pred poganima pravednost objavi."},{"v":3,"t":"Spomenu se dobrote i vjernosti prema domu Izraelovu. Svi krajevi svijeta vidješe spasenje Boga našega."},{"v":4,"t":"Sva zemljo, poklikni Jahvi, raduj se, kliči i pjevaj!"},{"v":5,"t":"Zapjevajte Jahvi uz citaru, uz citaru i uza zvuke harfe;"},{"v":6,"t":"uz trublje i zvuke rogova: kličite Jahvi kralju!"},{"v":7,"t":"Neka huči more i što je u njemu, krug zemaljski i stanovnici njegovi!"},{"v":8,"t":"Rijeke nek' plješću rukama, zajedno s njima neka se brda raduju!"},{"v":9,"t":"Jer Jahve dolazi, dolazi suditi zemlji. Vladat će krugom zemaljskim po pravdi i pucima po pravici."}]},"99":{"hr":[{"v":1,"t":"Jahve kraljuje - nek' zadršću narodi; sjedi nad kerubima - zemlja nek' se potrese!"},{"v":2,"t":"Velik je Jahve na Sionu, uzvišen nada sve narode."},{"v":3,"t":"Nek' slave ime tvoje veliko i strašno: ono je sveto!"},{"v":4,"t":"Ti kralj si moćan koji ljubiš što je pravo, pravednost ti si utvrdio, pravo i pravednost vršiš u Jakovu."},{"v":5,"t":"Uzvisujte Jahvu, Boga našega, padnite pred podnožje njegovo: ono je sveto."},{"v":6,"t":"Mojsije i Aron među svećenicima njegovim i Samuel među onima koji zazivaju ime njegovo: zazivahu Jahvu, i on ih usliša."},{"v":7,"t":"Iz stupa od oblaka govoraše njima: slušahu zapovijedi njegove i odredbe što ih dade."},{"v":8,"t":"Jahve, Bože naš, ti si ih uslišivao; Bože, milostiv si bio njima premda si kažnjavao grijehe njihove."},{"v":9,"t":"Uzvisujte Jahvu, Boga našega, padnite pred svetu goru njegovu: jer svet je Jahve, Bog naš."}]},"100":{"hr":[{"v":1,"t":"Psalam. Zahvalnica. Kliči Jahvi, zemljo sva!"},{"v":2,"t":"Služite Jahvi u veselju! Pred lice mu dođite s radosnim klicanjem!"},{"v":3,"t":"Znajte da je Jahve Bog: on nas stvori, i mi smo njegovi, njegov smo narod i ovce paše njegove."},{"v":4,"t":"Uđite s hvalama na vrata njegova, u dvore njegove s pjesmama; hvalite ga, ime mu slavite!"},{"v":5,"t":"Jer dobar je Jahve, dovijeka je ljubav njegova, od koljena do koljena vjernost njegova."}]},"101":{"hr":[{"v":1,"t":"Davidov. Psalam. Da zapjevam o dobroti i pravdi, tebi, Jahve, da zasviram!"},{"v":2,"t":"Razmatrat ću put savršenstva: kad li ćeš k meni doći? Hodit ću u nedužnosti srca u domu svojemu."},{"v":3,"t":"Neću stavljati pred oči svoje ništa opako. Mrzim čovjeka koji čini zlo: on neće biti uza me."},{"v":4,"t":"Opako će srce biti daleko od mene; o zlu neću da znadem."},{"v":5,"t":"Tko kleveće bližnjeg u potaji, toga ću pogubiti. Čovjeka oholih očiju i srca naduta ja ne podnosim."},{"v":6,"t":"Pogled upravljam k vjernima na zemlji da sa mnom stanuju. Tko hodi putem nedužnim taj će mi služiti."},{"v":7,"t":"Neće prebivati u kući mojoj tko spletke snuje. Tko govori laži, neće opstati pred mojim očima."},{"v":8,"t":"Svaki ću dan istrebljivati sve zlikovce u zemlji; iskorijenit ću iz grada Jahvina sve koji čine bezakonje."}]},"102":{"hr":[{"v":1,"t":"Molitva nevoljnika koji je klonuo pa svoju tugu izlijeva"},{"v":2,"t":"Jahve, usliši molitvu moju, i vapaj moj k tebi da dođe!"},{"v":3,"t":"Nemoj sakrivati lice od mene u dan moje nevolje! Prigni k meni uho svoje: kad te prizovem, brzo me usliši!"},{"v":4,"t":"Jer moji dani nestaju poput dima, a moje kosti gore kao oganj."},{"v":5,"t":"Srce mi se suši kao pokošena trava i kruh svoj zaboravljam jesti."},{"v":6,"t":"Od snažnih jecaja mojih kosti mi uz kožu prionuše."},{"v":7,"t":"Sličan sam čaplji u pustinji, postah k'o ćuk na pustoj razvalini."},{"v":8,"t":"Ne nalazim sna i uzdišem k'o samotan vrabac na krovu."},{"v":9,"t":"Svagda me grde dušmani moji; mnome se proklinju što bjesne na me."},{"v":10,"t":"Pepeo jedem poput kruha, a piće svoje miješam sa suzama"},{"v":11,"t":"zbog tvoje ljutine i gnjeva, jer si me digao i bacio."},{"v":12,"t":"Moji su dani k'o oduljena sjena, a ja se, gle, sušim poput trave."},{"v":13,"t":"A ti, o Jahve, ostaješ dovijeka i tvoje ime kroza sva koljena."},{"v":14,"t":"Ustani, smiluj se Sionu: vrijeme je da mu se smiluješ - sada je čas!"},{"v":15,"t":"Jer milo je slugama tvojim kamenje njegovo, žale ruševine njegove."},{"v":16,"t":"Tad će se pogani bojati, Jahve, imena tvojega i svi kraljevi zemlje slave tvoje"},{"v":17,"t":"kad Jahve opet sazda Sion, kad se pokaže u slavi svojoj,"},{"v":18,"t":"kad se osvrne na prošnju ubogih i ne prezre molitve njihove."},{"v":19,"t":"Nek' se zapiše ovo za budući naraštaj, puk što nastane neka hvali Jahvu."},{"v":20,"t":"Jer Jahve gleda sa svog uzvišenog svetišta, s nebesa na zemlju gleda"},{"v":21,"t":"da čuje jauke sužnjeva, da izbavi smrti predane,"},{"v":22,"t":"da se na Sionu navijesti ime Jahvino i njegova hvala u Jeruzalemu"},{"v":23,"t":"kad se narodi skupe i kraljevstva da služe Jahvi."},{"v":24,"t":"Putem je istrošio sile moje, skratio mi dane."},{"v":25,"t":"Rekoh: “Bože moj, nemoj me uzeti u sredini dana mojih! Kroza sva koljena traju godine tvoje."},{"v":26,"t":"U početku utemelji zemlju, i nebo je djelo ruku tvojih."},{"v":27,"t":"Propast će, ti ćeš ostati, sve će ostarjeti kao odjeća. Mijenjaš ih poput haljine i nestaju:"},{"v":28,"t":"ti si uvijek isti - godinama tvojim nema kraja."},{"v":29,"t":"Djeca će tvojih slugu živjeti u miru i potomstvo će njihovo trajati pred tobom."}]},"103":{"hr":[{"v":1,"t":"Davidov. Blagoslivljaj Jahvu, dušo moja, i sve što je u meni, sveto ime njegovo!"},{"v":2,"t":"Blagoslivljaj Jahvu, dušo moja, i ne zaboravi dobročinstva njegova:"},{"v":3,"t":"on ti otpušta sve grijehe tvoje, on iscjeljuje sve slabosti tvoje;"},{"v":4,"t":"on ti od propasti čuva život, kruni te dobrotom i ljubavlju;"},{"v":5,"t":"život ti ispunja dobrima, k'o orlu ti se mladost obnavlja."},{"v":6,"t":"Jahve čini pravedna djela i potlačenima vraća pravicu,"},{"v":7,"t":"Mojsiju objavi putove svoje, sinovima Izraelovim djela svoja."},{"v":8,"t":"Milosrdan i milostiv je Jahve, spor na srdžbu i vrlo dobrostiv."},{"v":9,"t":"Jarostan nije za vječna vremena niti dovijeka plamti srdžba njegova."},{"v":10,"t":"Ne postupa s nama po grijesima našim niti nam plaća po našim krivnjama."},{"v":11,"t":"Jer kako je nebo visoko nad zemljom, dobrota je njegova s onima koji ga se boje."},{"v":12,"t":"Kako je istok daleko od zapada, tako udaljuje od nas bezakonja naša."},{"v":13,"t":"Kako se otac smiluje dječici, tako se Jahve smiluje onima što ga se boje."},{"v":14,"t":"Jer dobro zna kako smo sazdani, spominje se da smo prašina."},{"v":15,"t":"Dani su čovjekovi kao sijeno, cvate k'o cvijetak na njivi;"},{"v":16,"t":"jedva ga dotakne vjetar, i već ga nema, ne pamti ga više ni mjesto njegovo."},{"v":17,"t":"Al' ljubav Jahvina vječna je nad onima što ga se boje i njegova pravda nad sinovima sinova,"},{"v":18,"t":"nad onima što njegov Savez čuvaju i pamte mu zapovijedi da ih izvrše."},{"v":19,"t":"Jahve u nebu postavi prijestolje svoje, i kraljevska vlast svemir mu obuhvaća."},{"v":20,"t":"Blagoslivljajte Jahvu, svi anđeli njegovi, vi jaki u sili, što izvršujete naredbe njegove, poslušni riječi njegovoj!"},{"v":21,"t":"Blagoslivljajte Jahvu, sve vojske njegove, sluge njegove koje činite volju njegovu!"},{"v":22,"t":"Blagoslivljajte Jahvu, sva djela njegova, na svakome mjestu vlasti njegove: blagoslivljaj Jahvu, dušo moja!"}]},"104":{"hr":[{"v":1,"t":"Blagoslivljaj Jahvu, dušo moja, Jahve, Bože moj, silno si velik! Odjeven veličanstvom i ljepotom,"},{"v":2,"t":"svjetlošću ogrnut kao plaštem! Nebo si razapeo kao šator,"},{"v":3,"t":"na vodama sagradio dvorove svoje. Od oblaka praviš kola svoja, na krilima vjetrova putuješ."},{"v":4,"t":"Vjetrove uzimaš za glasnike, a žarki oganj za slugu svojega."},{"v":5,"t":"Zemlju si stavio na stupove njene: neće se poljuljati u vijeke vjekova,"},{"v":6,"t":"pokrio si je vodama bezdanim k'o haljinom, iznad bregova stajahu vode;"},{"v":7,"t":"na tvoju se prijetnju povukoše, od tvoje grmljavine zadrhtaše."},{"v":8,"t":"Bregovi se digoše, doline spustiše na mjesto koje si im odredio."},{"v":9,"t":"Odredio si granicu koju ne smiju prijeći, da opet ne pokriju zemlju."},{"v":10,"t":"Izvore svraćaš u potoke što žubore među brdima."},{"v":11,"t":"Oni poje sve živine poljske, divlji magarci žeđ gase u njima."},{"v":12,"t":"Uz njih se gnijezde ptice nebeske i pjevaju među granama."},{"v":13,"t":"Ti natapaš bregove iz dvorova svojih, zemlja se nasićuje plodom tvojih ruku."},{"v":14,"t":"Ti daješ te niče trava za stoku i bilje na korist čovjeku da izvede kruh iz zemlje"},{"v":15,"t":"i vino što razvedruje srce čovječje; da uljem lice osvježi i da kruh okrijepi srce čovjeku."},{"v":16,"t":"Stabla se Jahvina napajaju hranom, cedri libanonski koje on zasadi."},{"v":17,"t":"Ondje se ptice gnijezde, u čempresu dom je rodin."},{"v":18,"t":"Visoki bregovi daju kozorogu a pećine jazavcu sklonište."},{"v":19,"t":"Ti si stvorio mjesec da označuje vremena i sunce znade kada ima zaći."},{"v":20,"t":"Kad razastreš tmine i noć se spusti, tad se šuljaju u njoj životinje šumske."},{"v":21,"t":"Lavići riču za plijenom i od Boga hranu traže."},{"v":22,"t":"Kad sunce ograne, nestaju i liježu na ležaje."},{"v":23,"t":"Tad čovjek izlazi na dnevni posao i na rad do večeri."},{"v":24,"t":"Kako su brojna tvoja djela, o Jahve! Sve si to mudro učinio: puna je zemlja stvorenja tvojih."},{"v":25,"t":"Eno mora, velika i široka, u njemu vrve gmazovi bez broja, životinje male i velike."},{"v":26,"t":"Onud prolaze nemani, Levijatan kojeg stvori da se igra u njemu."},{"v":27,"t":"I sva ova bića željno čekaju da ih nahraniš na vrijeme."},{"v":28,"t":"Daješ li im, tada sabiru: otvaraš li ruku, nasite se dobrima."},{"v":29,"t":"Sakriješ li lice svoje, tad se rastuže; ako dah im oduzmeš, ugibaju i opet se u prah vraćaju."},{"v":30,"t":"Pošalješ li dah svoj, opet nastaju, i tako obnavljaš lice zemlje."},{"v":31,"t":"Neka dovijeka traje slava Jahvina: nek' se raduje Jahve u djelima svojim!"},{"v":32,"t":"On pogleda zemlju i ona se potrese, dotakne bregove, oni se zadime."},{"v":33,"t":"Pjevat ću Jahvi dokle god živim, svirat ću Bogu svome dokle god me bude."},{"v":34,"t":"Bilo mu milo pjevanje moje! Ja ću se radovati u Jahvi."},{"v":35,"t":"Nek' zločinci sa zemlje nestanu i bezbožnika nek' više ne bude! Blagoslivljaj Jahvu, dušo moja! Aleluja!"}]},"105":{"hr":[{"v":1,"t":"Hvalite Jahvu, prizivajte mu ime, navješćujte među narodima djela njegova!"},{"v":2,"t":"Pjevajte mu, svirajte mu, pripovijedajte sva njegova čudesa!"},{"v":3,"t":"Dičite se svetim imenom njegovim, neka se raduje srce onih što traže Jahvu!"},{"v":4,"t":"Tražite Jahvu i njegovu snagu, tražite svagda njegovo lice!"},{"v":5,"t":"Sjetite se čudesa koja učini, njegovih čuda i sudova usta njegovih!"},{"v":6,"t":"Abrahamov rod sluga je njegov, sinovi Jakovljevi njegovi izabranici!"},{"v":7,"t":"On je Jahve, Bog naš; po svoj su zemlji njegovi sudovi!"},{"v":8,"t":"On se uvijek sjeća svojega Saveza, riječi koju dade tisući naraštaja:"},{"v":9,"t":"Saveza koji sklopi s Abrahamom i zakletve svoje Izaku."},{"v":10,"t":"Ustanovi je kao zakon Jakovu, Izraelu vječni Savez,"},{"v":11,"t":"govoreći: “Tebi ću dati kanaansku zemlju kao dio u baštinu vašu.”"},{"v":12,"t":"Kad ih još bješe malo na broju, vrlo malo, i kad bjehu pridošlice u njoj,"},{"v":13,"t":"išli su od naroda do naroda, iz jednoga kraljevstva k drugom narodu,"},{"v":14,"t":"ali ne dopusti nikom da ih tlači, kažnjavaše zbog njih kraljeve:"},{"v":15,"t":"“Ne dirajte u moje pomazanike, ne nanosite zla mojim prorocima!”"},{"v":16,"t":"I on pozva glad na zemlju, sve zalihe uništi krušne."},{"v":17,"t":"Pred njima čovjeka posla: Josip u ropstvo bijaše prodan."},{"v":18,"t":"Sputaše uzama noge njegove, u gvožđe mu vrat staviše,"},{"v":19,"t":"dok se ne ispuni proroštvo njegovo, Jahvina ga riječ potvrdi."},{"v":20,"t":"Kralj naredi da ga driješe, narÄodÄa poglavar oslobodi njega."},{"v":21,"t":"Za domaćina ga stavi kući svojoj, za nadstojnika sveg imanja svoga,"},{"v":22,"t":"da velikaše njegove po volji uči i starce njegove mudrosti da vodi."},{"v":23,"t":"Tad Izrael u Egipat uđe, Jakov došljak bješe u Kamovoj zemlji."},{"v":24,"t":"Narod svoj umnoži veoma, učini ga jačim od dušmana."},{"v":25,"t":"Okrenu im srce da zamrze narod njegov, da slugama njegovim opaki budu."},{"v":26,"t":"Mojsija posla, slugu svoga, Arona, kog odabra."},{"v":27,"t":"Činjahu među njima znake njegove i čudesa u Kamovoj zemlji."},{"v":28,"t":"Posla tmine, i smrknu se, al' prkosiše oni riječima njegovim."},{"v":29,"t":"U krv im vode prometnu i pobi ribe njihove."},{"v":30,"t":"Zemljom im žabe provrvješe, prodriješe i u dvore kraljevske."},{"v":31,"t":"Reče, i muha roj doletje i komarci u sve kraje njine."},{"v":32,"t":"Mjesto kiše grÓad im dade, ognjene munje po njihovoj zemlji."},{"v":33,"t":"Udari im lozu i smokve, polomi stabla u krajima njinim."},{"v":34,"t":"Reče, i skakavci dođoše i bezbrojne gusjenice s njima."},{"v":35,"t":"U zemlji im proždriješe svu bilinu, proždriješe rod njihovih njiva."},{"v":36,"t":"Pobi sve prvorođene u njihovoj zemlji, sve prvine snage njihove."},{"v":37,"t":"Izvede ih sa srebrom i zlatom; u plemenima njinim bolesnih ne bješe."},{"v":38,"t":"Odlasku njihovu Egipat se obradova, jer ga od njih strah spopade."},{"v":39,"t":"Rasprostro je oblak kao pokrov i oganj da se obnoć sja."},{"v":40,"t":"Zamoliše, i dovede prepelice, nebeskim ih kruhom tad nahrani."},{"v":41,"t":"Hrid rascijepi, i provri voda, pustinjom poteče kao rijeka."},{"v":42,"t":"Tad se sjeti svete riječi svoje što je zada sluzi svome Abrahamu."},{"v":43,"t":"Puk svoj s klicanjem izvede i s veseljem izabrane svoje."},{"v":44,"t":"I dade im zemlje poganske, trud naroda baštiniše,"},{"v":45,"t":"da čuvaju naredbe njegove i zakone da mu paze. Aleluja!"}]},"106":{"hr":[{"v":1,"t":"Aleluja! Hvalite Jahvu jer je dobar, jer je vječna ljubav njegova!"},{"v":2,"t":"Tko će izreć' djela moći Jahvine, tko li mu iskazat' sve pohvale?"},{"v":3,"t":"Blaženi što drže naredbe njegove i čine pravo u svako doba!"},{"v":4,"t":"Sjeti me se, Jahve, po dobroti prema svome puku, pohodi me spasenjem svojim"},{"v":5,"t":"da uživam sreću izabranih tvojih, da se radujem radosti naroda tvoga, da tvojom se baštinom ponosim."},{"v":6,"t":"Zgriješismo kao oci naši, činismo bezakonje, bezbožno radismo."},{"v":7,"t":"Oci naši u Egiptu, nehajni za čudesa tvoja, ne spominjahu se velike ljubavi tvoje, već na Svevišnjeg digoše se na Crvenom moru."},{"v":8,"t":"Al' on ih izbavi rad' imena svoga da pokaže silu svoju."},{"v":9,"t":"Zapovjedi Crvenome moru, i presahnu ono, provede ih izmed valÄa kao kroz pustinju."},{"v":10,"t":"Iz ruku mrzitelja njih izbavi, oslobodi iz ruku dušmana."},{"v":11,"t":"I prekriše vode neprijatelje njine, ne ostade nijednoga od njih."},{"v":12,"t":"Vjerovahu riječima njegovim i hvale mu pjevahu."},{"v":13,"t":"Zaboraviše brzo djela njegova, ne uzdaše se u volju njegovu."},{"v":14,"t":"Pohlepi se daše u pustinji, iskušavahu Boga u samoći."},{"v":15,"t":"I dade im što iskahu, al' u duše njine on groznicu posla."},{"v":16,"t":"Zavidješe tada Mojsiju u taboru, Aronu, kog posveti Jahve."},{"v":17,"t":"Otvori se zemlja, Datana proždrije, Abiramovo pokri mnoštvo."},{"v":18,"t":"Oganj pade na sve mnoštvo njino i zlotvore plamen sažga."},{"v":19,"t":"Načiniše tele na Horebu, klanjahu se liku od zlata slivenu."},{"v":20,"t":"Zamijeniše Slavu svoju likom bika što proždire travu."},{"v":21,"t":"Zaboraviše Boga, koji ih izbavi u Egiptu znamenja čineći"},{"v":22,"t":"i čudesa u Kamovoj zemlji i strahote na Crvenome moru."},{"v":23,"t":"Već namisli da ih satre, al' Mojsije, izabranik njegov, zauze se za njih da srdžbu mu odvrati, te ih ne uništi."},{"v":24,"t":"Prezreše oni zemlju željkovanu ne vjerujuć' njegovoj riječi."},{"v":25,"t":"Mrmljahu pod šatorima svojim, ne poslušaše glasa Jahvina."},{"v":26,"t":"Zakle se tada podignutom rukom: sve će ih pokosit' u pustinji,"},{"v":27,"t":"potomstvo njino međ' narode razbacat', njih razasut' po zemljama."},{"v":28,"t":"Posvetiše se Baal Peoru i jedoše žrtve bogova mrtvih."},{"v":29,"t":"Razjariše ga nedjelima svojim, i on na njih pošast baci."},{"v":30,"t":"Al' se Pinhas diže, sud izvrši i pošasti nesta tada."},{"v":31,"t":"U zasluge to mu uđe u sva pokoljenja dovijeka."},{"v":32,"t":"Razjariše ga opet kraj voda meripskih, i Mojsija zlo pogodi zbog njih,"},{"v":33,"t":"jer mu duh već ogorčiše, nesmotrenu riječ izusti."},{"v":34,"t":"I ne istrijebiše naroda za koje im Jahve bješe naredio."},{"v":35,"t":"S poganima miješahu se, naučiše djela njina."},{"v":36,"t":"Štovahu likove njihove, koji im postaše zamka."},{"v":37,"t":"Žrtvovahu sinove svoje i svoje kćeri zlodusima."},{"v":38,"t":"Prolijevahu krv nevinu, krv sinova i kćeri svojih, koje žrtvovahu likovima kanaanskim. Zemlja bješe krvlju okaljana,"},{"v":39,"t":"djelima se svojim uprljaše, učiniše preljub svojim nedjelima."},{"v":40,"t":"Na svoj narod Jahve srdžbom planu, zgadi mu se njegova baština."},{"v":41,"t":"Predade ih u ruke pogana te vladahu njima mrzitelji njini."},{"v":42,"t":"Mučili ih neprijatelji i tlačili rukom svojom."},{"v":43,"t":"Prečesto ih izbavljaše, al' ga razjariše naumima svojim: pokošeni bjehu za bezakonja svoja."},{"v":44,"t":"On pogleda opet na nevolju njinu kad njihove molitve začu"},{"v":45,"t":"i sjeti se svog Saveza s njima, sažali se na njih u velikom milosrđu svome."},{"v":46,"t":"Učini da nađu milost u onih što ih bjehu zarobili."},{"v":47,"t":"Spasi nas, Jahve, Bože naš, i saberi nas od bezbožnih naroda da slavimo tvoje sveto ime, da se tvojom slavom ponosimo."},{"v":48,"t":"Blagoslovljen Jahve, Bog Izraelov, od vijeka dovijeka! I sav narod neka kaže: “Amen! Aleluja!”"}]},"107":{"hr":[{"v":1,"t":"Hvalite Jahvu jer je dobar, jer je dovijeka ljubav njegova!"},{"v":2,"t":"Tako nek' reknu svi otkupljenici koje Jahve otkupi iz ruke dušmanske"},{"v":3,"t":"i koje skupi iz svih zemalja, s istoka i sa zapada, sa sjevera i s juga."},{"v":4,"t":"Lutahu pustinjom, u samoći pustoj, puta ne nalazeć' do naseljena grada."},{"v":5,"t":"Gladni su bili, žeđu izmoreni, duša je klonula u njima."},{"v":6,"t":"Tada zavapiše Jahvi u svojoj tjeskobi, i on ih istrže iz svih nevolja."},{"v":7,"t":"Pravim ih putem pÓovede da stignu ka gradu naseljenu."},{"v":8,"t":"Neka hvale Jahvu za dobrotu njegovu, za čudesa njegova sinovima ljudskim!"},{"v":9,"t":"Jer gladnu dušu on nasiti, dušu izgladnjelu on napuni dobrima."},{"v":10,"t":"U mraku sjeđahu i u tmini, sputani bijedom i gvožđima,"},{"v":11,"t":"jer su prkosili besjedama Božjim i prezreli naum Svevišnjega."},{"v":12,"t":"Srce im stoga skrši patnjama: posrtahu, a ne bješe nikog da im pomogne."},{"v":13,"t":"Tada zavapiše Jahvi u svojoj tjeskobi i on ih istrže iz svih nevolja."},{"v":14,"t":"Izvede ih iz tmina i mraka, raskide okove njihove."},{"v":15,"t":"Neka hvale Jahvu za dobrotu njegovu, za čudesa njegova sinovima ljudskim!"},{"v":16,"t":"Jer razbi vrata mjedena i gvozdene polomi zasune."},{"v":17,"t":"Zbog svojih bezakonja bolovahu oni, ispaštajuć' svoje opačine:"},{"v":18,"t":"svako se jelo gadilo duši njihovoj, do vrata smrti oni dođoše."},{"v":19,"t":"Tada zavapiše Jahvi u svojoj tjeskobi i on ih istrže iz svih nevolja."},{"v":20,"t":"Riječ svoju posla da ih ozdravi i život im spasi od jame grobne."},{"v":21,"t":"Neka hvale Jahvu za dobrotu njegovu, za čudesa njegova sinovima ljudskim!"},{"v":22,"t":"Nek' prinose žrtve zahvalnice i kličući nek' djela njegova kazuju!"},{"v":23,"t":"Oni koji lađama zaploviše morem da po vodama silnim trguju:"},{"v":24,"t":"oni vidješe djela Jahvina, čudesa njegova na pučini."},{"v":25,"t":"On reče i olujni se vjetar uzvitla što u visinu diže valove mora."},{"v":26,"t":"Do neba se dizahu, u bezdan se spuštahu, u nevolji duša im ginula."},{"v":27,"t":"Teturahu i posrtahu kao pijani, sva ih je mudrost izdala."},{"v":28,"t":"Tada zavapiše Jahvi u svojoj tjeskobi i on ih istrže iz svih nevolja."},{"v":29,"t":"Smiri oluju u tih povjetarac, valovi morski umukoše."},{"v":30,"t":"Obradovaše se tišini, u željenu luku on ih povede."},{"v":31,"t":"Neka hvale Jahvu za dobrotu njegovu, za čudesa njegova sinovima ljudskim!"},{"v":32,"t":"Neka ga uzvisuju u narodnom zboru, neka ga hvale u vijeću staraca!"},{"v":33,"t":"On pretvori rijeke u pustinju, a izvore vodene u žednu zemlju;"},{"v":34,"t":"plodonosnu zemlju u slanu pustaru zbog zloće žitelja njezinih."},{"v":35,"t":"On obrati pustinju u jezero, a zemlju suhu u vodene izvore"},{"v":36,"t":"i naseli ondje izgladnjele te podigoše grad gdje će živjeti."},{"v":37,"t":"Zasijaše njive, posadiše vinograde što im doniješe obilnu ljetinu."},{"v":38,"t":"I on ih blagoslovi te se namnožiše silno i stada im se ne smanjiše."},{"v":39,"t":"Prorijeđeni bjehu i prezreni pod teretom patnja i nevolja."},{"v":40,"t":"Onaj što izlijeva prezir na knezove pusti ih da po bespuću pustom lutaju."},{"v":41,"t":"Iz nevolje pÓodiže ubogog i obitelji k'o stada ÓumnožÄi."},{"v":42,"t":"Videć' to, čestiti neka se raduju, a zloća neka sebi usta začepi!"},{"v":43,"t":"Tko je mudar nek' o svemu tom razmišlja i nek' uvidi dobrotu Jahvinu!"}]},"108":{"hr":[{"v":1,"t":"Pjesma. Psalam. Davidov."},{"v":2,"t":"Moje je srce sigurno, Bože, sigurno je srce moje: pjevat ću i svirati."},{"v":3,"t":"Probudi se, dušo moja! Probudi se, harfo i citaro! Probudit ću zoru jutarnju."},{"v":4,"t":"Hvalit ću te, Jahve, među narodima, među pucima tebi ću pjevati,"},{"v":5,"t":"jer do neba je dobrota tvoja, do oblaka tvoja vjernost."},{"v":6,"t":"Uzvisi se, Bože, nad nebesa, slava tvoja nek' je nad svom zemljom!"},{"v":7,"t":"Da ti se ljubimci izbave, desnicom pomozi, usliši nas!"},{"v":8,"t":"Bog reče u svom Svetištu: “Šekem ću razdijelit' kličući, dolinu ću Sukot izmjeriti."},{"v":9,"t":"Moj je Gilead, moj Manaše, Efrajim mi kaciga, Judeja žezlo moje!"},{"v":10,"t":"Moab je sud iz kojeg se umivam, na Edom ću baciti obuću, nad Filistejcem slaviti pobjedu!”"},{"v":11,"t":"Tko će me dovesti do utvrđena grada, tko će me dovesti do Edoma?"},{"v":12,"t":"Zar nećeš ti, o Bože, što nas odbaci? Zar nećeš više, Bože, sa četama našim?"},{"v":13,"t":"Pomozi nam protiv dušmana, jer je ljudska pomoć ništavna!"},{"v":14,"t":"S Božjom pomoću hrabro ćemo se boriti, Bog će zgaziti naše dušmane."}]},"109":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov. Bože, diko moja, nemoj šutjeti!"},{"v":2,"t":"Usta bezbožna i prijevarna na me se otvaraju, govore mi jezikom lažljivim,"},{"v":3,"t":"riječima me mržnje okružuju, bezrazložno me napadaju."},{"v":4,"t":"Za moju me ljubav oni optužuju, a ja se samo molim."},{"v":5,"t":"Uzvraćaju mi zlo za dobro, mržnju za ljubav moju."},{"v":6,"t":"“Digni protiv njega bezbožnika i tužitelj nek' mu stane zdesna!"},{"v":7,"t":"Kad mu se bude sudilo, nek' bude osuđen, i molitva mu se za grijeh uzela!"},{"v":8,"t":"Dani njegovi nek' budu malobrojni, njegovu službu nek' dobije drugi!"},{"v":9,"t":"Djeca njegova nek' postanu siročad, a njegova žena udovica!"},{"v":10,"t":"Nek' mu djeca budu skitnice, prosjaci, nek' budu bačena iz opustjelih domova!"},{"v":11,"t":"Nek' mu lihvar prigrabi sav posjed, tuđinci nek' razgrabe plod muke njegove!"},{"v":12,"t":"Nitko ne imao prema njemu samilosti, nitko se ne smilovao siročadi njegovoj!"},{"v":13,"t":"Neka mu se zatre potomstvo, u drugome koljenu neka se utrne ime njegovo!"},{"v":14,"t":"Spominjao se Jahve grijeha njegovih, i grijeh njegove majke nek' se ne izbriše:"},{"v":15,"t":"nek budu svagda Jahvi pred očima! Neka se sa zemlje izbriše spomen njihov!”"},{"v":16,"t":"Jer se ne spomenu da čini milosrđe, već proganjaše bijedna i uboga i u smrt gonjaše čovjeka srca shrvana."},{"v":17,"t":"Prokletstvo je ljubio, pa neka ga stigne; blagoslova ne htjede, daleko nek' je od njega!"},{"v":18,"t":"Prokletstvom nek' se odjene kao haljinom, neka kao voda uđe u njega i kao ulje u kosti njegove."},{"v":19,"t":"Bilo mu haljinom kojom se pokriva, pojas kojim se svagda paše!"},{"v":20,"t":"Tako nek' plati Jahve tužiteljima mojim koji zlo govore protiv duše moje!"},{"v":21,"t":"A ti, Jahve, Gospode, rad imena svog zauzmi se za me, spasi me jer je dobrostiva ljubav tvoja!"},{"v":22,"t":"Jer bijedan sam i ubog, i srce je moje ranjeno u meni."},{"v":23,"t":"K'o sjena što se naginje ja nestajem, progone me kao skakavca."},{"v":24,"t":"Od posta mi koljena klecaju i tijelo moje omrša."},{"v":25,"t":"Ruglom sam njima postao, kimaju glavom kad me vide."},{"v":26,"t":"Pomozi mi, Jahve, Bože moj, po doborti me svojoj spasi!"},{"v":27,"t":"Nek' upoznaju da je ovo ruka tvoja i da si ti ovo učinio, Jahve!"},{"v":28,"t":"Oni nek' proklinju, ti blagoslivljaj; nek' se postide koji se na me podižu, a sluga tvoj nek' se raduje!"},{"v":29,"t":"Stidom nek' se odjenu tužitelji moji i sramotom svojom nek' se k'o plaštem pokriju!"},{"v":30,"t":"Slavit ću Jahvu iz svega grla i hvalit' ga u veliku mnoštvu"},{"v":31,"t":"jer stoji s desne siromahu da mu dušu spasi od sudaca."}]},"110":{"hr":[{"v":1,"t":"Psalam. Davidov. Riječ Jahvina Gospodinu mojemu: “Sjedi mi zdesna dok ne položim dušmane za podnožje tvojim nogama!"},{"v":2,"t":"Žezlo tvoje moći protegnut će Jahve sa Siona: vladaj posred svojih neprijatelja!"},{"v":3,"t":"Spreman je tvoj narod u svetim odorama za dan tvog junaštva: kao rosa iz krila zorina uza te su mladi ratnici.”"},{"v":4,"t":"Zakleo se Jahve i neće se pokajati: “Dovijeka ti si svećenik po redu Melkisedekovu!”"},{"v":5,"t":"Gospodin ti je zdesna, on će oboriti kraljeve u dan gnjeva svojega."},{"v":6,"t":"On će sudit' narodima: bit će trupla na gomile, po svoj zemlji raskoljenih glava."},{"v":7,"t":"Na putu će se napit' iz potoka, visoko će dignuti glavu."}]},"111":{"hr":[{"v":1,"t":"Aleluja! $ALEF Hvalit ću Jahvu svim srcem svojim $BET u zboru pravednika, u zajednici njihovoj."},{"v":2,"t":"$GIMEL Silna su djela Jahvina, $DALET nek' razmišljaju o njima svi koji ih ljube."},{"v":3,"t":"$HE Sjajno je i veličanstveno djelo njegovo, $VAU i pravda njegova ostaje dovijeka."},{"v":4,"t":"$ZAJIN Čudesima svojim spomen postavi, $HET blag je Jahve i milosrdan."},{"v":5,"t":"$TET Hranu dade štovateljima svojim, $JOD dovijeka se sjeća svoga Saveza."},{"v":6,"t":"$KAF Silna djela svoja objavi svom narodu, $LAMED u posjed im dade zemlju pogana."},{"v":7,"t":"$MEM Djela ruku njegovih vjernost su i pravednost, $NUN stalne su sve naredbe njegove,"},{"v":8,"t":"$SAMEK utvrđene za sva vremena, dovijeka, $AJIN sazdane na istini i na pravdi."},{"v":9,"t":"$PE On posla spasenje svom narodu, $SADE Savez svoj postavi zauvijek: $KOF sveto je i časno ime njegovo!"},{"v":10,"t":"$REŠ Početak mudrosti strah Gospodnji! $ŠIN Mudro čine koji ga poštuju. $TAU Slava njegova ostaje dovijeka!"}]},"112":{"hr":[{"v":1,"t":"Aleluja! $ALEF Blago čovjeku koji se boji Jahve $BET i koji uživa u naredbama njegovim:"},{"v":2,"t":"$GIMEL moćno će mu biti na zemlji potomstvo, $DALET na pravednu će pokoljenju počivati blagoslov."},{"v":3,"t":"$HE Blagostanje i bogatstvo bit će u domu njegovu, $VAU njegova pravednost ostaje dovijeka."},{"v":4,"t":"$ZAJIN Čestitima sviće k'o svjetlost u tami: $HET blag, milosrdan i pravedan Jahve."},{"v":5,"t":"$TET Dobro je čovjeku koji je milostiv i daje u zajam, $JOD koji poslove svoje obavlja pravedno."},{"v":6,"t":"$KAF Dovijeka neće on posrnuti: $LAMED u vječnome će spomenu biti pravednik."},{"v":7,"t":"$MEM Žalosne se vijesti neće bojati, $NUN mirno je njegovo srce uzdajuć' se u Jahvu."},{"v":8,"t":"$SAMEK Hrabro mu je srce, ničeg se ne boji, $AJIN neprijatelje svoje prezire."},{"v":9,"t":"$PE On prosipa, daje sirotinji: $SADE pravednost njegova ostaje dovijeka, $KOF njegovo će se čelo slavno uzdići."},{"v":10,"t":"$REŠ Ljutito će to gledati bezbožnik, $ŠIN škrgutat će zubima i venuti, $TAU propast će želja opakih."}]},"113":{"hr":[{"v":1,"t":"Aleluja! Hvalite, sluge Jahvine, hvalite ime Jahvino!"},{"v":2,"t":"Blagoslovljeno ime Jahvino sada i dovijeka!"},{"v":3,"t":"Od istoka sunca do zalaska hvaljeno bilo ime Jahvino!"},{"v":4,"t":"Uzvišen je Jahve nad sve narode, slava njegova nebesa nadvisuje."},{"v":5,"t":"Tko je kao Jahve, Bog naš, koji u visinama stoluje"},{"v":6,"t":"i gleda odozgo nebo i zemlju?"},{"v":7,"t":"Podiže iz prašine uboga, iz gliba vadi siromaha"},{"v":8,"t":"da ga posadi s prvacima, s prvacima svoga naroda."},{"v":9,"t":"Nerotkinji daje da u domu stanuje kao radosna majka djece brojne."}]},"114":{"hr":[{"v":1,"t":"Aleluja! Kad izađe Izrael iz Egipta i kuća Jakovljeva iz naroda barbarskog,"},{"v":2,"t":"Judeja mu posta svetište, a Izrael kraljevstvo njegovo."},{"v":3,"t":"Vidje more i uzmače, a Jordan ustuknu."},{"v":4,"t":"Bregovi skakahu poput ovnova i brežuljci poput jaganjaca."},{"v":5,"t":"Što ti je, more, da uzmičeš? Jordane, zašto natrag okrećeš?"},{"v":6,"t":"Bregovi, zašto skačete poput ovnova i vi, brežuljci, poput jaganjaca?"},{"v":7,"t":"Dršći, zemljo, pred licem Gospodnjim, pred licem Boga Jakovljeva."},{"v":8,"t":"On hrid pretvara u slap vodeni i stijenu u izvor vode."}]},"115":{"hr":[{"v":1,"t":"Ne nama, o Jahve, ne nama, već svom imenu slavu daj zbog ljubavi i vjernosti svoje."},{"v":2,"t":"Zašto da govore pogani: “TÓa gdje je Bog njihov?”"},{"v":3,"t":"Naš je Bog na nebesima, sve što mu se svidi to učini."},{"v":4,"t":"Idoli su njihovi srebro i zlato, ljudskih su ruku djelo."},{"v":5,"t":"Usta imaju, a ne govore, oči imaju, a ne vide."},{"v":6,"t":"Uši imaju, a ne čuju, nosnice, a ne mirišu."},{"v":7,"t":"Ruke imaju, a ne hvataju, noge imaju, a ne hodaju; glas im iz grla ne izlazi."},{"v":8,"t":"Takvi su i oni koji ih napraviše i svi koji se u njih uzdaju."},{"v":9,"t":"Dome Izraelov, u Jahvu se uzdaj! - On je štit i pomoćnik njihov."},{"v":10,"t":"Dome Aronov, u Jahvu se uzdaj! - On je štit i pomoćnik njihov."},{"v":11,"t":"Štovatelji Jahvini, u Jahvu se uzdajte! - On je štit i pomoćnik njihov."},{"v":12,"t":"Jahve će se nas spomenut' i on će nas blagoslovit': blagoslovit će dom Izraelov, blagoslovit će dom Aronov,"},{"v":13,"t":"blagoslovit će one koji se Jahve boje - i male i velike."},{"v":14,"t":"Umnožio vas Jahve, vas i vaše sinove!"},{"v":15,"t":"Blagoslovio vas Jahve koji stvori nebo i zemlju!"},{"v":16,"t":"Nebo je nebo Jahvino, a zemlju dade sinovima čovječjim."},{"v":17,"t":"Ne, Jahvu mrtvi ne hvale, nitko od onih što siđu u Podzemlje."},{"v":18,"t":"Mi živi, mi Jahvu slavimo sada i dovijeka. Aleluja."}]},"116":{"hr":[{"v":1,"t":"Ljubim Jahvu jer čuje vapaj molitve moje:"},{"v":2,"t":"uho svoje prignu k meni u dan u koji ga zazvah."},{"v":3,"t":"Užeta smrti sapeše me, stegoše me zamke Podzemlja, snašla me muka i tjeskoba."},{"v":4,"t":"Tada zazvah ime Jahvino: “O Jahve, spasi život moj!”"},{"v":5,"t":"Dobrostiv je Jahve i pravedan, pun sućuti je Bog naš."},{"v":6,"t":"Jahve čuva bezazlene: u nevolji bijah, on me izbavi."},{"v":7,"t":"Vrati se, dušo moja, u svoj pokoj, jer Jahve je dobrotvor tvoj."},{"v":8,"t":"On mi život od smrti izbavi, oči moje od suza, noge od pada."},{"v":9,"t":"Hodit ću pred licem Jahvinim u zemlji živih."},{"v":10,"t":"Ja vjerujem i kada kažem: “Nesretan sam veoma.”"},{"v":11,"t":"U smetenosti svojoj rekoh: “Svaki je čovjek lažac!”"},{"v":12,"t":"Što da uzvratim Jahvi za sve što mi je učinio?"},{"v":13,"t":"Uzet ću čašu spasenja i zazvat ću ime Jahvino."},{"v":14,"t":"Izvršit ću Jahvi zavjete svoje pred svim pukom njegovim."},{"v":15,"t":"Dragocjena je u očima Jahvinim smrt pobožnika njegovih."},{"v":16,"t":"Jahve, tvoj sam sluga, tvoj sluga, sin sluškinje tvoje: ti si razriješio okove moje."},{"v":17,"t":"Tebi ću prinijeti žrtve zahvalne, zazvat ću ime Jahvino."},{"v":18,"t":"Izvršit ću Jahvi zavjete svoje pred svim pukom njegovim,"},{"v":19,"t":"u predvorjima Doma Jahvina, posred tebe, Jeruzaleme!"}]},"117":{"hr":[{"v":1,"t":"Aleluja! Hvalite Jahvu, svi puci, slavite ga, svi narodi!"},{"v":2,"t":"Silna je prema nama ljubav njegova, i vjernost Jahvina ostaje dovijeka!"}]},"118":{"hr":[{"v":1,"t":"Aleluja! Zahvaljujte Jahvi jer je dobar, jer je vječna ljubav njegova!"},{"v":2,"t":"Neka rekne dom Izraelov: “Vječna je ljubav njegova!”"},{"v":3,"t":"Neka rekne dom Aronov: “Vječna je ljubav njegova!”"},{"v":4,"t":"Svi koji se Jahve boje neka reknu: “Vječna je ljubav njegova!”"},{"v":5,"t":"Iz tjeskobe Jahvu ja zazvah: on me usliša i oslobodi."},{"v":6,"t":"Jahve je sa mnom i ja ne strahujem: što mi tko može?"},{"v":7,"t":"Jahve je sa mnom, pomoć moja, i zbunjene gledam dušmane."},{"v":8,"t":"Bolje se Jahvi uteći nego se uzdat' u čovjeka."},{"v":9,"t":"Bolje se Jahvi uteći nego se uzdat' u mogućnike."},{"v":10,"t":"Pogani me okružiše: imenom ih Jahvinim uništih."},{"v":11,"t":"Opkoliše me odasvud: imenom ih Jahvinim uništih."},{"v":12,"t":"Opkoliše me poput pčela, ubod im žeže kao trnje zapaljeno: imenom ih Jahvinim uništih."},{"v":13,"t":"Gurahu me, gurahu, da me obore, ali mi Jahve pomože."},{"v":14,"t":"Jahve je moja snaga i pjesma, on mi je spasitelj."},{"v":15,"t":"Čuj! Radost i spasenje odzvanja šatorima pravednika: Jahvina se proslavi desnica,"},{"v":16,"t":"Jahvina me uzdigne desnica, Jahvina se proslavi desnica!"},{"v":17,"t":"Ne, umrijeti neću nego živjeti i kazivat ću djela Jahvina."},{"v":18,"t":"Kaznom teškom kaznio me Jahve, ali me smrti ne preda."},{"v":19,"t":"Otvorite mi širom vrata pravde: ući ću, Jahvi zahvalit'!"},{"v":20,"t":"“Ovo su vrata Jahvina, na njih ulaze pravedni!”"},{"v":21,"t":"Zahvalit ću ti što si me uslišio i moj postao spasitelj."},{"v":22,"t":"Kamen što ga odbaciše graditelji postade kamen zaglavni."},{"v":23,"t":"Jahvino je to djelo: kakvo čudo u očima našim!"},{"v":24,"t":"Ovo je dan što ga učini Jahve: kličimo i radujmo se njemu!"},{"v":25,"t":"O Jahve, spasenje nam daj! Jahve, sreću nam daj!"},{"v":26,"t":"Blagoslovljen koji dolazi u imenu Jahvinu! Blagoslivljamo vas iz Doma Jahvina!"},{"v":27,"t":"Obasjao nas Bog Jahve! Složite povorku s grančicama u ruci sve do rogova žrtvenika."},{"v":28,"t":"Ti si Bog moj - tebi zahvaljujem: Bože moj, tebe ja uzvisujem."},{"v":29,"t":"Zahvaljujte Jahvi jer je dobar, jer je vječna ljubav njegova!"}]},"119":{"hr":[{"v":1,"t":"$ALEF Blaženi oni kojih je put neokaljan, koji hode po Zakonu Jahvinu!"},{"v":2,"t":"Blaženi oni koji čuvaju propise njegove, čitavim srcem njega traže;"},{"v":3,"t":"koji ne čine bezakonje, već hode putovima njegovim."},{"v":4,"t":"Naredbe si svoje dao da se brižno čuvaju."},{"v":5,"t":"O, kad bi čvrsti bili putovi moji da tvoja čuvam pravila!"},{"v":6,"t":"Neću se postidjeti tada kad budem pazio na zapovijedi tvoje."},{"v":7,"t":"Slavit ću te u čestitosti srca kad naučim sudove pravde tvoje."},{"v":8,"t":"Tvoja ću pravila čuvati: ne zapusti me nikada!"},{"v":9,"t":"$BET Kako će mladić čistim sačuvati put svoj? Čuvajući riječi tvoje."},{"v":10,"t":"Svim srcem svojim tebe tražim; ne daj da zastranim od zapovijedi tvojih."},{"v":11,"t":"U srce pohranih riječ tvoju da protiv tebe ne sagriješim."},{"v":12,"t":"Blagoslovljen si, o Jahve, nauči me svojim pravilima."},{"v":13,"t":"Usnama svojim navješćujem sudove usta tvojih."},{"v":14,"t":"Putu se propisa tvojih radujem više no svemu bogatstvu."},{"v":15,"t":"Razmišljat ću o naredbama tvojim i putove ću tvoje razmatrat'."},{"v":16,"t":"Uživat ću u pravilima tvojim, riječi tvojih neću zaboravit'."},{"v":17,"t":"$GIMEL Milostiv budi meni, sluzi svojem, da živim i tvoje riječi čuvam."},{"v":18,"t":"Otvori oči moje da gledam divote tvoga Zakona!"},{"v":19,"t":"Ja sam došljak na zemlji, zapovijedi svoje nemoj od mene skrivati!"},{"v":20,"t":"Duša mi gine u svako doba žudeći za tvojim odlukama."},{"v":21,"t":"Oholima ti si zaprijetio: prokleti koji odstupaju od zapovijedi tvojih."},{"v":22,"t":"Uzmi s mene rug i sramotu, jer tvoje ja čuvam propise."},{"v":23,"t":"Pa nek' se sastaju knezovi i proti meni govore, tvoj sluga razmišlja o pravilima tvojim."},{"v":24,"t":"Jer tvoja su svjedočanstva uživanje moje, tvoja su pravila moji savjetnici."},{"v":25,"t":"$DALET Moja duša leži u prašini: po riječi svojoj vrati mi život."},{"v":26,"t":"Kazivao sam ti svoje putove i ti si me čuo: pravilima me svojim nauči."},{"v":27,"t":"Pokaži mi put odredaba svojih i o čudesima ću tvojim razmišljat'."},{"v":28,"t":"Suze roni duša moja od žalosti: po riječi svojoj ti me podigni!"},{"v":29,"t":"Daleko me drži od puta zablude i Zakonom me svojim obdari!"},{"v":30,"t":"Put istine ja sam odabrao, pred oči sam stavio odluke tvoje."},{"v":31,"t":"Uz propise tvoje ja čvrsto prianjam, o Jahve, nemoj me postidjeti!"},{"v":32,"t":"Ja kročim putem zapovijedi tvojih jer si mi prosvijetlio srce."},{"v":33,"t":"$HE Pokaži mi, Jahve, stazu pravila svojih i ja ću je čuvati do kraja."},{"v":34,"t":"Pouči me da se tvoga držim Zakona i čuvat ću ga svim srcem."},{"v":35,"t":"Uputi me stazom svojih zapovijedi, jer ja u njoj uživam."},{"v":36,"t":"Prikloni mi srce propisima svojim, a ne k pohlepi!"},{"v":37,"t":"Odvrati moje oči da ne vide ništavost, život mi čuvaj na putu svojemu!"},{"v":38,"t":"Ispuni svom sluzi obećanje koje si onima dao što te se boje."},{"v":39,"t":"Ukloni sramotu od koje strahujem, jer divni su tvoji sudovi."},{"v":40,"t":"Evo, čeznem za naredbama tvojim: pravdom me svojom poživi."},{"v":41,"t":"$VAU Nek' milost tvoja, o Jahve, dođe na mene i spasenje tvoje po tvom obećanju."},{"v":42,"t":"Odgovorit ću onima koji me ruže, jer se uzdam u riječ tvoju."},{"v":43,"t":"Od mojih usta ne oduzmi riječ istine, jer se uzdam u sudove tvoje."},{"v":44,"t":"Tvoj ću Zakon čuvati uvijek i dovijeka."},{"v":45,"t":"Hodit ću putem prostranim, jer naredbe tvoje istražujem."},{"v":46,"t":"Pred kraljevima o tvojim ću propisima govorit' i zbunit' se neću."},{"v":47,"t":"U zapovijedima tvojim moja je naslada jer ih ljubim."},{"v":48,"t":"Prema zapovijedima tvojim ja podižem ruke i o tvojim odredbama razmišljam."},{"v":49,"t":"$ZAJIN Spomeni se svoje riječi sluzi svojem kojom si mi dao nadu."},{"v":50,"t":"U nevolji sva mi je utjeha što mi život čuva riječ tvoja."},{"v":51,"t":"Oholice me napadaju žestoko, ali ja od tvog Zakona ne odstupam."},{"v":52,"t":"Sjećam se, o Jahve, davnih sudova tvojih i to me tješi."},{"v":53,"t":"Bijes me hvata zbog grešnika koji tvoj Zakon napuštaju."},{"v":54,"t":"Tvoje su mi naredbe pjesma u zemlji kojom putujem."},{"v":55,"t":"Noću se spominjem, Jahve, imena tvojega i tvoj čuvam Zakon."},{"v":56,"t":"Evo što je želja moja: čuvati tvoje odredbe."},{"v":57,"t":"$HET Dio je moj, o Jahve - rekoh - da tvoje čuvam riječi."},{"v":58,"t":"Svim srcem lice tvoje ganuti hoću: smiluj mi se po svom obećanju."},{"v":59,"t":"Promislio sam putove svoje i k tvojem sam svjedočanstvu upravio noge."},{"v":60,"t":"Hitam i ne oklijevam da zapovijedi tvoje čuvam."},{"v":61,"t":"Opletoše me užeta grešnika, ali tvoga Zakona ja ne zaboravljam."},{"v":62,"t":"U ponoći ustajem da te slavim zbog pravednih tvojih odluka."},{"v":63,"t":"Prijatelj sam svima koji te se boje i koji tvoje čuvaju naredbe."},{"v":64,"t":"Dobrote tvoje, Jahve, puna je zemlja; nauči me odredbama svojim."},{"v":65,"t":"$TET Učinio si dobro svom sluzi, Jahve, po riječi svojoj."},{"v":66,"t":"Nauči me razumu i znanju, jer u zapovijedi tvoje vjerujem."},{"v":67,"t":"Prije nego bjeh ponižen, lutao sam, ali sada tvoju čuvam riječ."},{"v":68,"t":"Ti si tako dobar i dobrostiv: nauči me pravilima svojim."},{"v":69,"t":"Oholi na me prijevare smišljaju, ali se ja svim srcem držim naredaba tvojih."},{"v":70,"t":"Srce im je poput sala bešćutno, a ja uživam u tvom Zakonu."},{"v":71,"t":"Dobro mi je što sam ponižen da bih tvoja naučio pravila."},{"v":72,"t":"Draži mi je zakon usta tvojih no tisuće zlatnika i srebrnika."},{"v":73,"t":"$JOD Tvoje me ruke stvoriše i oblikovaše; prosvijetli me da naučim zapovijedi tvoje."},{"v":74,"t":"Štovatelji tvoji videć' me vesele se, jer se u riječ tvoju ja pouzdah."},{"v":75,"t":"Znadem, o Jahve, da su ti sudovi pravedni i da si me s pravom ponizio."},{"v":76,"t":"Tvoja ljubav nek' mi bude tješiteljicom po obećanju koje si dao sluzi svom."},{"v":77,"t":"Nek' dođe na me milosrđe tvoje da poživim, jer Zakon tvoj moja je naslada."},{"v":78,"t":"Nek' se smetu oholi, jer me tlače nizašto, a ja ću o naredbama tvojim razmišljat'."},{"v":79,"t":"Nek' mi se priklone štovatelji tvoji i koji znaju tvoje zapovijedi."},{"v":80,"t":"Nek' mi srce savršeno bude u tvojim pravilima da ne budem postiđen."},{"v":81,"t":"$KAF Duša moja gine za tvojim spasenjem riječ tvoju željno čekam."},{"v":82,"t":"Oči mi čeznu za tvojom besjedom: kad ćeš mi donijeti utjehu?"},{"v":83,"t":"Kao mijeh u dimu postadoh, ali pravila tvojih ne zaboravih."},{"v":84,"t":"Koliko dana ima sluga tvoj? Kad ćeš suditi progonitelje moje?"},{"v":85,"t":"Oholnici mi jame iskopaše: oni ne rade po Zakonu tvojemu."},{"v":86,"t":"Sve zapovijedi tvoje istina su sama: nekriva me gone, pomozi mi."},{"v":87,"t":"Umalo me smrviše u zemlji, ali naredaba tvojih ja ne ostavljam."},{"v":88,"t":"Po svojoj me milosti poživi i čuvat ću svjedočanstvo tvojih usta."},{"v":89,"t":"$LAMED Dovijeka, o Jahve, riječ tvoja ostaje, stalna poput nebesa."},{"v":90,"t":"od koljena do koljena tvoja je vjernost; učvrstio si zemlju i ona stoji."},{"v":91,"t":"Po tvojim zakonima stoje zauvijek jer sve tebi služi."},{"v":92,"t":"Da nije tvoj Zakon uživanje moje, propao bih u nevolji svojoj."},{"v":93,"t":"Naredaba tvojih neću zaboravit' dovijeka, jer po njima ti me oživljavaš."},{"v":94,"t":"Tvoj sam, Gospodine: spasi me, jer tvoje ja ištem naredbe."},{"v":95,"t":"Bezbožni vrebaju da me upropaste, ali ja na tvoje pazim propise."},{"v":96,"t":"Svakom savršenstvu vidim granicu, a zapovijed tvoja nema granica."},{"v":97,"t":"$MEM O, kako ljubim Zakon tvoj, po cio dan o njemu razmišljam."},{"v":98,"t":"Tvoja me zapovijed mudrijim učini od dušmana mojih jer ona je sa mnom vječito."},{"v":99,"t":"Umniji sam od svih svojih učitelja jer razmišljam o svjedočanstvima tvojim."},{"v":100,"t":"Razumniji sam i od staraca jer tvoje čuvam naredbe."},{"v":101,"t":"Zla puta klone mi se noge da riječ tvoju sačuvam."},{"v":102,"t":"Od tvojih sudova ne odstupam, jer ti si me poučio."},{"v":103,"t":"Kako su slatke nepcu mom riječi tvoje, od meda su slađe ustima mojim."},{"v":104,"t":"Po tvojim naredbama postajem razuman, stoga mrzim sve putove lažne."},{"v":105,"t":"$NUN Tvoja riječ nozi je mojoj svjetiljka i svjetlo mojoj stazi."},{"v":106,"t":"Kunem se i čvrsto odlučujem, i riječ ću održati: pravedne ću tvoje slijedit' odluke."},{"v":107,"t":"U nevolji sam velikoj, Jahve, po riječi me svojoj poživi."},{"v":108,"t":"Prinose usta mojih primi, Jahve, uči me sudovima svojim."},{"v":109,"t":"Život mi je u pogibelji neprestanoj, ali tvog Zakona ja ne zaboravljam."},{"v":110,"t":"Grešnici mi postaviše zamku, ali ne skrećem od tvojih naredaba."},{"v":111,"t":"Svjedočanstva tvoja vječna su mi baština, ona su radost mome srcu."},{"v":112,"t":"Prignuh srce da vrši naredbe tvoje uvijek i do kraja."},{"v":113,"t":"$SAMEK Ja mrzim one koji su dvostruka srca, a ljubim Zakon tvoj."},{"v":114,"t":"Ti si moj štit i moj zaklon, u tvoju se riječ ja uzdam."},{"v":115,"t":"Odstupite od mene, zlikovci: držat ću zapovijedi Boga svoga."},{"v":116,"t":"Podrži me po svom obećanju i živjet ću; nemoj da se u svojoj nadi postidim."},{"v":117,"t":"Pomozi mi i spasit ću se, na tvoja ću pravila svagda paziti."},{"v":118,"t":"Ti prezireš one koji odstupaju od pravila tvojih jer je lažna misao njihova."},{"v":119,"t":"K'o hrđu zlotvore zemlje uklanjaš, zato ljubim tvoje propise."},{"v":120,"t":"Moje tijelo dršće od straha pred tobom, sudova tvojih ja se bojim."},{"v":121,"t":"$AJIN Činim što je pravo i pravedno, ne predaj me tlačiteljima mojim."},{"v":122,"t":"Založi se za slugu svojega da me ne satru oholice!"},{"v":123,"t":"Moje oči ginu od čežnje za spasenjem tvojim, za tvojom riječi pravednom."},{"v":124,"t":"Učini sluzi svom po svojoj dobroti i nauči me pravilima svojim."},{"v":125,"t":"Ja sam sluga tvoj: prosvijetli me da upoznam tvoje propise."},{"v":126,"t":"Čas je, o Jahve, da se javiš: oskvrnuše Zakon tvoj."},{"v":127,"t":"Stoga ljubim zapovijedi tvoje više no zlato, zlato žeženo."},{"v":128,"t":"Zato hodim po odredbama tvojim, mrski su mi svi lažni putovi."},{"v":129,"t":"$PE Divna su tvoja svjedočanstva, stoga ih čuva duša moja."},{"v":130,"t":"Objava riječi tvojih prosvjetljuje, bezazlene urazumljuje."},{"v":131,"t":"Otvaram usta svoja zadahtan u žudnji jer čeznem za zapovijedima tvojim."},{"v":132,"t":"Obrati se k meni i milostiv mi budi kao onima koji ljube ime tvoje."},{"v":133,"t":"Korake mi upravljaj po svom obećanju da nikakva opačina ne ovlada mnome."},{"v":134,"t":"Izbavi me od nasilja ljudskog, i naredbe tvoje ja ću čuvati."},{"v":135,"t":"Licem svojim obasjaj slugu svog i nauči me pravilima svojim!"},{"v":136,"t":"Potoci suza potekoše mi iz očiju jer se Zakon tvoj ne čuva."},{"v":137,"t":"$SADE Pravedan si, Jahve, i pravi su sudovi tvoji."},{"v":138,"t":"Dao si Zakon pravedan i vjeran veoma."},{"v":139,"t":"Revnost me moja izjeda jer moji tlačitelji zaboravljaju riječi tvoje."},{"v":140,"t":"Tvoje su riječi prokušane veoma, zato ih tvoj sluga ljubi."},{"v":141,"t":"Malen sam i prezren, ali naredaba tvojih ne zaboravljam."},{"v":142,"t":"Pravda je tvoja pravda vječita i Zakon tvoj sama istina."},{"v":143,"t":"Tjeskoba me i nevolja snađe, al' tvoje su zapovijedi uživanje moje."},{"v":144,"t":"Vječna je pravda tvojeg svjedočanstva, prosvijetli me i živjet ću."},{"v":145,"t":"$KOF Iz svega srca vapijem, Jahve, usliši me: tvoja ću pravila čuvati."},{"v":146,"t":"K tebi vapijem, spasi me, tvojeg ću se držat' svjedočanstva."},{"v":147,"t":"Pretječem zoru i molim za pomoć, u tvoje se riječi uzdam."},{"v":148,"t":"Oči moje straže noćne pretječu da razmišljam o besjedi tvojoj."},{"v":149,"t":"Po svojoj dobroti, Jahve, glas mi poslušaj, i po svojoj odluci poživi me."},{"v":150,"t":"Primiču se koji me podlo progone, daleko su oni od Zakona tvojega."},{"v":151,"t":"A ti si blizu, Jahve, i vjerne su sve zapovijedi tvoje."},{"v":152,"t":"Odavno znam za tvoje propise da si ih sazdao zasvagda."},{"v":153,"t":"$REŠ Pogledaj na nevolju moju, izbavi me, jer Zakona tvog ne zaboravih."},{"v":154,"t":"Parnicu moju brani, po svom obećanju poživi me!"},{"v":155,"t":"Daleko je spasenje od grešnika jer za pravila tvoja ne mare."},{"v":156,"t":"Veliko je, o Jahve, tvoje smilovanje: po odlukama svojim poživi me."},{"v":157,"t":"Mnogi me progone i tlače, od tvojih svjedočanstava ja ne odstupam."},{"v":158,"t":"Otpadnike vidjeh i zgadiše mi se jer tvojih riječi ne čuvaju."},{"v":159,"t":"Gle, naredbe tvoje ljubim, o Jahve: po dobroti svojoj poživi me."},{"v":160,"t":"Srž je riječi tvoje istina, vječan je sud pravde tvoje."},{"v":161,"t":"$ŠIN Mogućnici me progone nizašto, al' samo pred tvojim riječima srce mi dršće."},{"v":162,"t":"Radujem se besjedama tvojim kao onaj koji se domogao velika plijena."},{"v":163,"t":"Mrzim na laž, grsti mi se ona, a ljubim tvoj Zakon."},{"v":164,"t":"Sedam puta na dan tebe hvalim zbog pravednih sudova tvojih."},{"v":165,"t":"Koji tvoj Zakon ljube, velik mir uživaju, ni o što se oni ne spotiču."},{"v":166,"t":"Pomoć tvoju čekam, o Jahve, tvoje zapovijedi izvršavam."},{"v":167,"t":"Moja duša čuva propise tvoje i ljubi ih veoma."},{"v":168,"t":"Čuvam tvoje naredbe i svjedočanstvo tvoje, jer svi su putovi moji pred tobom."},{"v":169,"t":"$TAU Vapaj moj, Jahve, nek' do tebe dopre, po svojoj me riječi prosvijetli."},{"v":170,"t":"Nek' molitva moja dođe pred lice tvoje, po svojoj me riječi izbavi."},{"v":171,"t":"Usne moje nek' zapjevaju pohvalnu pjesmu jer si me naučio pravilima svojim."},{"v":172,"t":"Nek' mi pjeva jezik o riječi tvojoj, jer zapovijedi su tvoje sve pravedne."},{"v":173,"t":"Nek' mi ruka tvoja na pomoć bude jer odabrah tvoje naredbe."},{"v":174,"t":"Jahve, za tvojim spasenjem čeznem, uživam u tvom Zakonu."},{"v":175,"t":"Nek' živi duša moja i neka te hvali, a tvoji sudovi nek' mi na pomoć budu!"},{"v":176,"t":"K'o ovca izgubljena ja zalutah: o, potraži slugu svojega jer zapovijedi tvoje ja ne zaboravih."}]},"120":{"hr":[{"v":1,"t":"Hodočasnička pjesma Kad bijah u nevolji, Jahvi zavapih i on me usliša."},{"v":2,"t":"Jahve, izbavi dušu moju od usana prijevarnih, od zlobna jezika!"},{"v":3,"t":"Kojim zlom da te prokunem, zlobni jeziče?"},{"v":4,"t":"Strelicama oštrim iz ratničke ruke i ugljevljem žarkim."},{"v":5,"t":"Jao meni što mi je boraviti u Mešeku i stanovati u šatorima kedarskim!"},{"v":6,"t":"Predugo mi duša mora živjeti s mrziteljima mira."},{"v":7,"t":"Kada o miru govorim, oni sile na rat."}]},"121":{"hr":[{"v":1,"t":"Hodočasnička pjesma. K brdima oči svoje uzdižem: odakle će mi doći pomoć?"},{"v":2,"t":"Pomoć je moja od Jahve koji stvori nebo i zemlju."},{"v":3,"t":"Tvojoj nozi on posrnuti ne da i neće zadrijemati on, čuvar tvoj."},{"v":4,"t":"Ne, ne drijema i ne spava on, čuvar Izraelov."},{"v":5,"t":"Jahve je čuvar tvoj, Jahve je zasjen tvoj s desne tvoje!"},{"v":6,"t":"Neće ti sunce nauditi danju ni mjesec noću."},{"v":7,"t":"Čuvao te Jahve od zla svakoga, čuvao dušu tvoju!"},{"v":8,"t":"Čuvao Jahve tvoj izlazak i povratak odsada dovijeka."}]},"122":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Davidova. Obradovah se kad mi rekoše: “Hajdemo u Dom Jahvin!”"},{"v":2,"t":"Eto, noge nam već stoje na vratima tvojim, Jeruzaleme."},{"v":3,"t":"Jeruzaleme, grade čvrsto sazdani i kao u jedno saliveni!"},{"v":4,"t":"Onamo uzlaze plemena, plemena Jahvina, po Zakonu Izraelovu, da slave ime Jahvino."},{"v":5,"t":"Ondje stoje sudačke stolice, stolice doma Davidova."},{"v":6,"t":"Molite za mir Jeruzalemov! Blago onima koji tebe ljube!"},{"v":7,"t":"Neka bude mir u zidinama tvojim i pokoj u tvojim palačama!"},{"v":8,"t":"Radi braće i prijatelja svojih klicat ću: “Mir tebi!”"},{"v":9,"t":"Radi Doma Jahve, Boga našega, za sreću tvoju ja ću moliti."}]},"123":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Oči svoje uzdižem k tebi koji u nebesima prebivaš."},{"v":2,"t":"Evo, kao što su uprte oči slugu u ruke gospodara i oči sluškinje u ruke gospodarice tako su oči naše uprte u Jahvu, Boga našega, dok nam se ne smiluje."},{"v":3,"t":"Smiluj nam se, Jahve, smiluj se nama jer se do grla nasitismo prezira."},{"v":4,"t":"Presita nam je duša podsmijeha obijesnih, poruga oholih."}]},"124":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Davidova. Da nije Jahve za nas bio - neka slobodno rekne Izrael -"},{"v":2,"t":"da nije Jahve za nas bio: kad se ljudi digoše proti nama,"},{"v":3,"t":"žive bi nas progutali. Kad je uskipio bijes njihov na nas,"},{"v":4,"t":"voda bi nas podavila; bujica bi nas odnijela,"},{"v":5,"t":"vode pobješnjele sve nas potopile."},{"v":6,"t":"Blagoslovljen Jahve koji nas ne dade za plijen zubima njihovim!"},{"v":7,"t":"Duša je naša poput ptice umakla iz zamke lovaca: raskinula se zamka, a mi umakosmo!"},{"v":8,"t":"Pomoć je naša u imenu Jahve koji stvori nebo i zemlju."}]},"125":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Tko se uzda u Jahvu, on je kao brdo Sion: ne pomiče se, ostaje dovijeka."},{"v":2,"t":"Bregovi okružuju Jeruzalem: Jahve okružuje narod svoj odsada i dovijeka."},{"v":3,"t":"I neće vladati žezlo bezbožničko nad udesom pravednih, da ne bi pravedni ruke za bezakonjem pružili."},{"v":4,"t":"Učini, Jahve, dobro dobrima i čestitima u srcu."},{"v":5,"t":"A koji na krive skreću putove nek' ih istrijebi Jahve sa zločincima! Mir nad Izraelom!"}]},"126":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Kad Jahve vraćaše sužnjeve sionske, bilo nam je k'o da snivamo."},{"v":2,"t":"Usta nam bjehu puna smijeha, a jezik klicanja. Među poganima tad se govorilo: “Velika im djela Jahve učini!”"},{"v":3,"t":"Velika nam djela učini Jahve: opet smo radosni!"},{"v":4,"t":"Vrati, o Jahve, sužnjeve naše k'o potoke negepske!"},{"v":5,"t":"Oni koji siju u suzama, žanju u pjesmi."},{"v":6,"t":"Išli su plačući noseći sjeme sjetveno: vraćat će se s pjesmom, noseći snoplje svoje."}]},"127":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Salomonova. Ako Jahve kuću ne gradi, uzalud se muče graditelji. Ako Jahve grad ne čuva, uzalud stražar bdi."},{"v":2,"t":"Uzalud vam je ustat prije zore i dugo u noć sjediti, vi što jedete kruh muke: miljenicima svojim u snu on daje."},{"v":3,"t":"Evo: sinovi su Jahvin dar, plod utrobe njegova je nagrada."},{"v":4,"t":"Strelica u ruci ratnika - to su sinovi mladosti."},{"v":5,"t":"Blago čovjeku koji njima napuni tobolac, neće se postidjeti kad se prÓeo bude s dušmanom na vratima."}]},"128":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Blago svakome koji se Jahve boji, koji njegovim hodi stazama!"},{"v":2,"t":"Plod ruku svojih ti ćeš uživati, blago tebi, dobro će ti biti."},{"v":3,"t":"Žena će ti biti kao plodna loza u odajama tvoje kuće; sinovi tvoji k'o mladice masline oko stola tvojega."},{"v":4,"t":"Eto, tako će biti blagoslovljen čovjek koji se Jahve boji!"},{"v":5,"t":"Blagoslovio te Jahve sa Siona, uživao sreću Jeruzalema sve dane života svog!"},{"v":6,"t":"Vidio djecu svojih sinova, mir nad Izraelom!"}]},"129":{"hr":[{"v":1,"t":"Hodočasnička pjesma. “Mnogo su me od mladosti tlačili” - neka rekne sad Izrael!"},{"v":2,"t":"“Mnogo su me od mladosti tlačili, ali me ne svladaše."},{"v":3,"t":"Po leđima su mojim orači orali, duge brazde povlačili."},{"v":4,"t":"Al' Jahve pravedni isiječe užeta zlikovcima!”"},{"v":5,"t":"Nek' se postide i uzmaknu svi koji mrze Sion!"},{"v":6,"t":"Nek' budu k'o trava na krovu što povene prije nego je počupaju."},{"v":7,"t":"Žetelac njome ne napuni ruku ni naručje onaj koji veže snopove."},{"v":8,"t":"A prolaznici nek' ne reknu: “Blagoslov Jahvin nad vama! Blagoslivljamo vas imenom Jahvinim!”"}]},"130":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Iz dubine, Jahve, vapijem tebi:"},{"v":2,"t":"Gospodine, čuj glas moj! Neka pazi uho tvoje na glas moga vapaja!"},{"v":3,"t":"Ako se, Jahve, grijeha budeš spominjao, Gospodine, tko će opstati?"},{"v":4,"t":"Al' u tebe je praštanje, da bi te se bojali."},{"v":5,"t":"U Jahvu ja se uzdam, duša se moja u njegovu uzda riječ."},{"v":6,"t":"Duša moja čeka Gospodina više no zoru straža noćna; više no zoru straža noćna"},{"v":7,"t":"nek' Izrael čeka Jahvu. Jer je u Jahve milosrđe i obilno je u njega otkupljenje;"},{"v":8,"t":"on će otkupiti Izraela od svih grijeha njegovih."}]},"131":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Davidova. O Jahve, ne gordi se moje srce niti se oči uznose. Ne idem za stvarima velikim ni za čudima što su iznad mene."},{"v":2,"t":"Ne, ja sam se smirio i upokojio dušu svoju; kao dojenče na grudima majke, kao dojenče duša je moja u meni."},{"v":3,"t":"U Jahvu se, Izraele, uzdaj odsada dovijeka."}]},"132":{"hr":[{"v":1,"t":"Hodočasnička pjesma."},{"v":2,"t":"Spomeni se, o Jahve, Davida i sve revnosti njegove: kako se Jahvi zakleo, zavjetovao Snazi Jakovljevoj:"},{"v":3,"t":"“Neću ući u šator doma svog nit' uzaći na ležaj svoje postelje,"},{"v":4,"t":"neću pustit' snu na oči nit' počinka dati vjeđama,"},{"v":5,"t":"dok Jahvi mjesto ne nađem, boravište Snazi Jakovljevoj.”"},{"v":6,"t":"Eto, čusmo za nj u Efrati, nađosmo ga u Poljima jaarskim."},{"v":7,"t":"Uđimo u stan njegov, pred noge mu padnimo!"},{"v":8,"t":"“Ustani, o Jahve, pođi k svom počivalištu, ti i Kovčeg sile tvoje!"},{"v":9,"t":"Svećenici tvoji nek' se obuku u pravednost, pobožnici tvoji nek' radosno kliču!"},{"v":10,"t":"Poradi Davida, sluge svojega, ne odvrati lica od svog pomazanika!”"},{"v":11,"t":"Jahve se zakle Davidu zakletvom tvrdom od koje neće odustati: “Potomka tvoje utrobe posadit ću na prijestolje tvoje."},{"v":12,"t":"Budu li ti sinovi Savez moj čuvali i naredbe kojima ih učim, i sinovi će njini dovijeka sjedit' na tvom prijestolju.”"},{"v":13,"t":"Jer Jahve odabra Sion, njega zaželje sebi za sjedište."},{"v":14,"t":"“Ovo mi je počivalište vječno, boravit ću ovdje jer tako poželjeh."},{"v":15,"t":"Žitak ću njegov blagosloviti, siromahe nahraniti kruhom."},{"v":16,"t":"Svećenike njegove u spas ću odjenuti, sveti će njegovi kliktati radosno."},{"v":17,"t":"Učinit ću da ondje za Davida rog izraste, pripravit ću svjetiljku za svog pomazanika."},{"v":18,"t":"U sram ću mu obući dušmane, a na njemu će blistat' vijenac moj.”"}]},"133":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Davidova. Gle, kako je dobro i kako je milo kao braća zajedno živjeti:"},{"v":2,"t":"kao na glavi ulje dragocjeno što slazi na bradu, bradu Aronovu, što slazi na skute haljina njegovih;"},{"v":3,"t":"kao rosa s Hermona što slazi na brdo Sion. Ondje Jahve daje svoj blagoslov i život dovijeka."}]},"134":{"hr":[{"v":1,"t":"Hodočasnička pjesma. Sad, blagoslivljajte Jahvu, sve sluge Jahvine što stojite u Domu Jahvinu, u noćnim satima!"},{"v":2,"t":"Dižite svoje ruke prema Svetištu i Jahvu blagoslivljajte!"},{"v":3,"t":"“Blagoslovio te sa Siona Jahve koji stvori nebo i zemlju!”"}]},"135":{"hr":[{"v":1,"t":"Aleluja! Hvalite ime Jahvino, hvalite, sluge Jahvine"},{"v":2,"t":"koji u Domu Jahvinu stojite u predvorjima Doma Boga našega!"},{"v":3,"t":"Hvalite Jahvu jer dobar je Jahve, pjevajte imenu njegovu jer je ljupko!"},{"v":4,"t":"Jer Jahve sebi odabra Jakova, Izraela za dragu svojinu."},{"v":5,"t":"Znadem da je velik Jahve, da je nad bozima svim gospodar."},{"v":6,"t":"Što god se Jahvi svidi, to čini na nebu i na zemlji, na moru i u bezdanima."},{"v":7,"t":"Oblake diže s kraja zemlje; stvara kiši munje, vjetar izvodi iz skrovišta njegovih."},{"v":8,"t":"On Egiptu pobi prvorođence, ljude i stoku podjednako."},{"v":9,"t":"On učini znamenja i čudesa usred tebe, Egipte, protiv Faraona i svih slugu njegovih."},{"v":10,"t":"On pobi narode mnoge i pogubi kraljeve moćne:"},{"v":11,"t":"Sihona, kralja amorejskog, i Oga, kralja bašanskog, i sva kraljevstva kanaanska."},{"v":12,"t":"I dade njihovu zemlju u baštinu, u baštinu Izraelu, narodu svom."},{"v":13,"t":"Ime tvoje, o Jahve, ostaje dovijeka i spomen na te, o Jahve, od koljena do koljena."},{"v":14,"t":"Jer Jahve štiti narod svoj, slugama svojim on je milostiv."},{"v":15,"t":"Kumiri poganski, srebro i zlato, ljudskih su ruku djelo:"},{"v":16,"t":"usta imaju, a ne govore; oči imaju, a ne vide;"},{"v":17,"t":"uši imaju, a ne čuju; i nema daha u ustima njihovim."},{"v":18,"t":"Takvi su i oni koji ih napraviše i svi koji se u njih uzdaju."},{"v":19,"t":"Dome Izraelov, Jahvu blagoslivljaj! Dome Aronov, Jahvu blagoslivljaj!"},{"v":20,"t":"Dome Levijev, Jahvu blagoslivljaj! Štovatelji Jahvini, Jahvu blagoslivljajte!"},{"v":21,"t":"Blagoslovljen sa Siona Jahve koji prebiva u Jeruzalemu!"}]},"136":{"hr":[{"v":1,"t":"Aleluja! Hvalite Jahvu jer je dobar: vječna je ljubav njegova!"},{"v":2,"t":"Hvalite Boga nad bogovima: vječna je ljubav njegova!"},{"v":3,"t":"Hvalite Gospodara nad gospodarima: vječna je ljubav njegova!"},{"v":4,"t":"Jedini on učini čuda velika: vječna je ljubav njegova!"},{"v":5,"t":"Mudro sazda on nebesa: vječna je ljubav njegova!"},{"v":6,"t":"On utvrdi zemlju nad vodama: vječna je ljubav njegova!"},{"v":7,"t":"On načini svjetlila velika: vječna je ljubav njegova!"},{"v":8,"t":"Sunce da vlada danom: vječna je ljubav njegova!"},{"v":9,"t":"Mjesec i zvijezde da vladaju noću: vječna je ljubav njegova!"},{"v":10,"t":"On pobi prvorođence Egiptu: vječna je ljubav njegova!"},{"v":11,"t":"Izvede Izraela iz njega: vječna je ljubav njegova!"},{"v":12,"t":"Mišicom jakom, rukom ispruženom: vječna je ljubav njegova!"},{"v":13,"t":"On Crveno more razdvoji: vječna je ljubav njegova!"},{"v":14,"t":"Provede Izraela posred voda: vječna je ljubav njegova!"},{"v":15,"t":"I vrgnu Faraona i vojsku mu u Crveno more: vječna je ljubav njegova!"},{"v":16,"t":"On narod svoj vođaše pustinjom: vječna je ljubav njegova!"},{"v":17,"t":"On udari kraljeve velike: vječna je ljubav njegova!"},{"v":18,"t":"I pogubi kraljeve moćne: vječna je ljubav njegova!"},{"v":19,"t":"Sihona, kralja amorejskog: vječna je ljubav njegova!"},{"v":20,"t":"Oga, kralja bašanskog: vječna je ljubav njegova!"},{"v":21,"t":"I njihovu zemlju dade u baštinu: vječna je ljubav njegova!"},{"v":22,"t":"U baštinu Izraelu, sluzi svome: vječna je ljubav njegova!"},{"v":23,"t":"On se spomenu nas u poniženju našem: vječna je ljubav njegova!"},{"v":24,"t":"Od dušmana nas naših oslobodi: vječna je ljubav njegova!"},{"v":25,"t":"On daje hrane svakom tijelu: vječna je ljubav njegova!"},{"v":26,"t":"Hvalite Boga nebeskog: vječna je ljubav njegova!"}]},"137":{"hr":[{"v":1,"t":"Na obali rijeka babilonskih sjeđasmo i plakasmo spominjući se Siona;"},{"v":2,"t":"o vrbe naokolo harfe svoje bijasmo povješali."},{"v":3,"t":"I tada naši tamničari zaiskaše od nas da pjevamo, porobljivači naši zaiskaše da se veselimo: “Pjevajte nam pjesmu sionsku!”"},{"v":4,"t":"Kako da pjesmu Jahvinu pjevamo u zemlji tuđinskoj!"},{"v":5,"t":"Nek' se osuši desnica moja, Jeruzaleme, ako tebe zaboravim!"},{"v":6,"t":"Nek' mi se jezik za nepce prilijepi ako spomen tvoj smetnem ja ikada, ako ne stavim Jeruzalem vrh svake radosti svoje!"},{"v":7,"t":"Ne zaboravi, Jahve, sinovima Edoma kako su u dan kobni Jeruzalemov vikali oni: “Rušite! Srušite ga do temelja!”"},{"v":8,"t":"Kćeri babilonska, pustošiteljice, blažen koji ti vrati milo za drago za sva zla što si nam ih nanijela!"},{"v":9,"t":"Blažen koji zgrabi i smrska o stijenu tvoju dojenčad!"}]},"138":{"hr":[{"v":1,"t":"Davidov. Zahvaljujem ti, Jahve, iz svega srca jer si čuo riječi mojih usta. Pred licem anđela pjevam tebi,"},{"v":2,"t":"bacam se nice prema svetom Hramu tvojemu. Zahvaljujem imenu tvojem za tvoju dobrotu i vjernost, jer si nada sve uzveličao obećanje svoje."},{"v":3,"t":"Kad sam te zazvao, uslišio si me, dušu si moju pokrijepio."},{"v":4,"t":"Nek' ti zahvaljuju, Jahve, svi kraljevi zemlje kad čuju riječi usta tvojih,"},{"v":5,"t":"nek' pjevaju putove Jahvine: “Zaista, velika je slava Jahvina!”"},{"v":6,"t":"Zaista, uzvišen je Jahve, ali gleda na ponizna, a oholicu izdaleka poznaje."},{"v":7,"t":"Kroz nevolje kad budem kročio, život mi čuvaj, pruži ruku proti gnjevu mojih dušmana; nek' me tvoja spasi desnica!"},{"v":8,"t":"Jahve, što ja počeh, ti dovrši! Jahve, vječna je ljubav tvoja: djelo ruku svojih ne zapusti!"}]},"139":{"hr":[{"v":1,"t":"Zborovođi. Davidov. Jahve, proničeš me svega i poznaješ,"},{"v":2,"t":"ti znaš kada sjednem i kada ustanem, izdaleka ti već misli moje poznaješ."},{"v":3,"t":"Hodam li ili ležim, sve ti vidiš, znani su ti svi moji putovi."},{"v":4,"t":"Riječ mi još nije na jezik došla, a ti, Jahve, sve već znadeš."},{"v":5,"t":"S leđa i s lica ti me obuhvaćaš, na mene si ruku svoju stavio."},{"v":6,"t":"Znanje to odveć mi je čudesno, previsoko da bih ga dokučio."},{"v":7,"t":"Kamo da idem od duha tvojega i kamo da od tvog lica pobjegnem?"},{"v":8,"t":"Ako se na nebo popnem, ondje si, ako u Podzemlje legnem, i ondje si."},{"v":9,"t":"Uzmem li krila zorina pa se naselim moru na kraj"},{"v":10,"t":"i ondje bi me ruka tvoja vodila, desnica bi me tvoja držala."},{"v":11,"t":"Reknem li: “Nek' me barem tmine zakriju i nek' me noć umjesto svjetla okruži!” -"},{"v":12,"t":"ni tmina tebi neće biti tamna: noć sjaji kao dan i tama kao svjetlost."},{"v":13,"t":"Jer ti si moje stvorio bubrege, satkao me u krilu majčinu."},{"v":14,"t":"Hvala ti što sam stvoren tako čudesno, što su djela tvoja predivna. Dušu moju do dna si poznavao,"},{"v":15,"t":"kosti moje ne bjehu ti sakrite dok nastajah u tajnosti, otkan u dubini zemlje."},{"v":16,"t":"Oči tvoje već tada gledahu djela moja, sve već bješe zapisano u knjizi tvojoj: dani su mi određeni dok još ne bješe ni jednoga."},{"v":17,"t":"Kako su mi, Bože, naumi tvoji nedokučivi, kako li je neprocjenjiv zbroj njihov."},{"v":18,"t":"Da ih brojim? Više ih je nego pijeska! Dođem li im do kraja, ti mi preostaješ!"},{"v":19,"t":"De, istrijebi, Bože, zlotvora, krvoloci nek' odstupe od mene!"},{"v":20,"t":"Jer podmuklo se bune protiv tebe, uzalud se dižu tvoji dušmani."},{"v":21,"t":"Jahve, zar da ne mrzim tvoje mrzitelje? Zar da mi se ne gade protivnici tvoji?"},{"v":22,"t":"Mržnjom dubokom ja ih mrzim i držim ih svojim neprijateljima."},{"v":23,"t":"Pronikni me svega, Bože, srce mi upoznaj, iskušaj me i upoznaj misli moje:"},{"v":24,"t":"pogledaj, ne idem li putem pogubnim i povedi me putem vječnim!"}]},"140":{"hr":[{"v":1,"t":"Zborovođi. Psalam. Davidov."},{"v":2,"t":"Izbavi me, Jahve, od čovjeka zlobna, zaštiti me od čovjeka nasilna:"},{"v":3,"t":"od onih koji pakosti u srcu smišljaju i čitav dan začinju kavge."},{"v":4,"t":"Kao zmije bruse jezike svoje, pod usnama im je otrov ljutičin."},{"v":5,"t":"Spasi me, Jahve, od ruku zlotvora, čuvaj me od čovjeka nasilna koji hoće da mi noga posrne."},{"v":6,"t":"Oholice mi potajno nastavljaju zamku, užetima mrežu pletu, kraj puta klopke mi stavljaju."},{"v":7,"t":"Zavapih Jahvi: “Ti si Bog moj! Poslušaj, o Jahve, krik mojih molitava!"},{"v":8,"t":"Jahve, Gospode moj, spasitelju silni moj, u dan boja zakloni mi glavu!”"},{"v":9,"t":"Ne daj da se ispune želje zlotvora, ne daj da svoje on izvrši namjere!"},{"v":10,"t":"Nek' glavu ne podignu oni koji me opkoliše, nek' na njih padne zloba njihovih usana!"},{"v":11,"t":"Nek' daždi po njima ugljevlje ognjeno, nek' se strovale u jamu da više ne ustanu!"},{"v":12,"t":"Opadač se neće održat' na zemlji, silnika će odjednom zgrabiti nesreća."},{"v":13,"t":"Znam da će Jahve dati pravo ubogu i pravicu siromasima."},{"v":14,"t":"Zaista, pravedni će tvoje ime slaviti, pred tvojim će licem boraviti čestiti."}]},"141":{"hr":[{"v":1,"t":"Psalam. Davidov. Prizivljem te, Jahve, k meni pohitaj! Slušaj glas moj kojim tebi vapijem!"},{"v":2,"t":"Nek' mi se uzdigne molitva kao kad pred lice tvoje, podizanje mojih ruku nek' bude k'o prinos večernji!"},{"v":3,"t":"Na usta mi, Jahve, stražu postavi i stražare na vrata usana mojih!"},{"v":4,"t":"Ne daj da mi se srce zlu prikloni, da bezbožno počinim djela opaka; i u društvu zlotvora da ne blagujem poslastica njihovih!"},{"v":5,"t":"Nek' me samo udari pravednik, ljubav je što me kara, al' ulje grešničko neće mi glavu pomazat'; zloći njihovoj oprijet ću se uvijek svojom molitvom."},{"v":6,"t":"Kad strovale niz hridinu suce njihove, razumjet će kako blage bjehu riječi moje."},{"v":7,"t":"Kao kad orač ore i para zemlju, tako će im se na rubu Podzemlja kosti rasuti."},{"v":8,"t":"U te su, Jahve, uprte oči moje, k tebi se utječem, ne daj da mi duša propadne!"},{"v":9,"t":"Čuvaj me od stupice koju postaviše meni, od zamki zločinaca!"},{"v":10,"t":"Nek' u vlastite zamke upadnu zlotvori, a ja neka im umaknem!"}]},"142":{"hr":[{"v":1,"t":"Poučna pjesma. Davidova. Kad bijaše u spilji. Molitva."},{"v":2,"t":"Iz svega glasa vapijem Jahvi, iz svega glasa Jahvu zaklinjem."},{"v":3,"t":"Pred njim svoju izlijevam tužaljku, tjeskobu svoju pred njim razastirem."},{"v":4,"t":"Ako duh moj i klone u meni, ti put moj poznaješ. Na putu kojim prolazim potajnu mi zamku staviše."},{"v":5,"t":"Obazrem li se nadesno i pogledam: nitko ne zna za mene. Nemam kamo pobjeći, nitko za život moj ne mari."},{"v":6,"t":"K tebi, Jahve, vapijem; govorim: ti si mi utočište, ti si dio moj u zemlji živih."},{"v":7,"t":"Poslušaj moje vapaje jer sam veoma nevoljan. Izbavi me od gonitelja mojih jer od mene oni su moćniji."},{"v":8,"t":"Izvedi iz tamnice dušu moju da zahvaljujem imenu tvojemu. Oko mene će se okupiti pravednici zbog dobra što si ga iskazao meni."}]},"143":{"hr":[{"v":1,"t":"Psalam. Davidov. Jahve, slušaj moju molitvu, u vjernosti svojoj prikloni uho mojim vapajima, u pravednosti me svojoj usliši!"},{"v":2,"t":"Ne idi na sud sa slugom svojim, jer nitko živ nije pravedan pred tobom!"},{"v":3,"t":"Dušmanin mi dušu progoni, o zemlju pritisnu život moj; u tmine me baci da stanujem kao oni koji su davno umrli."},{"v":4,"t":"Duh moj već zamire u meni, srce mi trne u grudima."},{"v":5,"t":"Spominjem se dana minulih, mislim o svim djelima tvojim, o djelima ruku tvojih razmišljam."},{"v":6,"t":"Ruke svoje za tobom pružam, duša moja k'o suha zemlja za tobom žeđa."},{"v":7,"t":"Usliši me brzo, o Jahve, dah moj već je na izmaku! Lica svojeg preda mnom ne skrivaj, da ne postanem kao oni koji u grob silaze!"},{"v":8,"t":"Objavi mi jutrom dobrotu svoju jer se uzdam u tebe. Put mi kaži kojim ću krenuti jer k tebi dušu uzdižem."},{"v":9,"t":"Izbavi me, Jahve, od mojih dušmana, tebi ja se utječem."},{"v":10,"t":"Nauči me da vršim volju tvoju jer ti si Bog moj. Duh tvoj dobri nek' me po ravnu putu vodi!"},{"v":11,"t":"Zbog imena svog, Jahve, poživi me, zbog svoje pravednosti dušu mi izvedi iz tjeskobe!"},{"v":12,"t":"Po svojoj dobroti satri moje dušmane, uništi sve moje tlačitelje, jer ja sam sluga tvoj!"}]},"144":{"hr":[{"v":1,"t":"Davidov. Blagoslovljen Jahve, hridina moja: ruke mi uči boju a prste ratu."},{"v":2,"t":"On je ljubav moja i tvrđava moja, zaštita moja, izbavitelj moj, štit moj za koji se sklanjam; on mi narode stavlja pod noge!"},{"v":3,"t":"Što je čovjek, o Jahve, da ga poznaješ, što li čedo ljudsko da ga se spominješ?"},{"v":4,"t":"Poput daška je čovjek, dani njegovi kao sjena nestaju."},{"v":5,"t":"Jahve, nagni svoja nebesa i siđi, takni bregove: i zadimit će se!"},{"v":6,"t":"Sijevni munjom i rasprši dušmane, odapni strijele i rasprši ih!"},{"v":7,"t":"Ruku pruži iz visina, istrgni me i spasi iz voda beskrajnih, iz šaka sinova tuđinskih:"},{"v":8,"t":"laži govore usta njihova, a desnica krivo priseže."},{"v":9,"t":"Pjevat ću ti, Bože, pjesmu novu, na harfi od deset žica svirat ću."},{"v":10,"t":"Ti daješ pobjedu kraljevima, koji si spasio Davida, slugu svojega. Od pogubna mača"},{"v":11,"t":"spasi mene, oslobodi me iz ruke tuđinske; laži govore usta njihova, a desnica krivo priseže."},{"v":12,"t":"Daj da nam sinovi budu kao biljke što rastu od mladosti svoje; a kćeri naše kao stupovi ugaoni, krasne poput hramskog stupovlja;"},{"v":13,"t":"da nam žitnice budu pune svakog obilja, s plodovima svakojakim u izobilju;"},{"v":14,"t":"ovce naše plodile se na tisuće, plodile se beskrajno na našim poljima; stoka naša neka bude tovna! U zidinama nam ne bilo proboja ni ropstva ni plača na ulicama našim!"},{"v":15,"t":"Blago narodu kojem je tako, blago narodu kojem je Jahve Bog!"}]},"145":{"hr":[{"v":1,"t":"Hvalospjev. Davidov. $ALEF Slavit ću te, o Bože, kralju moj, ime ću tvoje blagoslivljat' uvijek i dovijeka."},{"v":2,"t":"$BET Svaki ću dan tebe slaviti, ime ću tvoje hvaliti uvijek i dovijeka. $GIMEL"},{"v":3,"t":"Velik je Jahve i svake hvale dostojan, nedokučiva je veličina njegova! $DALET"},{"v":4,"t":"Naraštaj naraštaju kazuje djela tvoja i silu tvoju naviješta."},{"v":5,"t":"$HE Govore o blistavoj slavi tvoga veličanstva i čudesa tvoja objavljuju."},{"v":6,"t":"$VAU Kazuju strahovitu silu djela tvojih, veličinu tvoju pripovijedaju."},{"v":7,"t":"$ZAJIN Razglašuju spomen velike dobrote tvoje i pravednosti tvojoj kliču."},{"v":8,"t":"$HET Milostiv je Jahve i milosrdan, spor na srdžbu, bogat dobrotom."},{"v":9,"t":"$TET Gospodin je dobar svima, milosrdan svim djelima svojim."},{"v":10,"t":"$JOD Nek' te slave, Jahve, sva djela tvoja i tvoji sveti nek' te blagoslivlju!"},{"v":11,"t":"$KAF Neka kazuju slavu tvoga kraljevstva, neka o sili tvojoj govore"},{"v":12,"t":"$LAMED da objave ljudskoj djeci silu tvoju i slavu divnoga kraljevstva tvoga."},{"v":13,"t":"$MEM Kraljevstvo tvoje kraljevstvo je vječno, tvoja vladavina za sva pokoljenja. $NUN Vjeran je Jahve u svim riječima svojim i svet u svim svojim djelima."},{"v":14,"t":"$SAMEK Jahve podupire sve koji posrću i pognute on uspravlja."},{"v":15,"t":"$AJIN Oči sviju u tebe su uprte, ti im hranu daješ u pravo vrijeme."},{"v":16,"t":"$PE Ti otvaraš ruku svoju, do mile volje sitiš sve živo."},{"v":17,"t":"$SADE Pravedan si, Jahve, na svim putovima svojim i svet u svim svojim djelima."},{"v":18,"t":"$KOF Blizu je Jahve svima koji ga prizivlju, svima koji ga zazivaju iskreno."},{"v":19,"t":"$REŠ On ispunja želje štovatelja svojih, sluša njihove vapaje i spasava ih."},{"v":20,"t":"$ŠIN Jahve štiti one koji njega ljube, a zlotvore sve će zatrti."},{"v":21,"t":"$TAU Nek' usta moja kazuju hvalu Jahvinu i svako tijelo nek' slavi sveto ime njegovo - uvijek i dovijeka."}]},"146":{"hr":[{"v":1,"t":"Aleluja! Hvali, dušo moja, Jahvu!"},{"v":2,"t":"Hvalit ću Jahvu sveg života svojeg. Dok me bude, Bogu svom ću pjevati."},{"v":3,"t":"Ne uzdajte se u knezove, u čovjeka od kog nema spasenja!"},{"v":4,"t":"Iziđe li duh iz njega, u zemlju svoju on se vraća i propadaju sve misli njegove."},{"v":5,"t":"Blago onom kome je pomoćnik Bog Jakovljev, kome je ufanje u Jahvi, Bogu njegovu,"},{"v":6,"t":"koji stvori nebo i zemlju, more i sve što je u njima; koji ostaje vjeran dovijeka,"},{"v":7,"t":"potlačenima vraća pravicu, a gladnima kruh daje. Jahve oslobađa sužnje,"},{"v":8,"t":"Jahve slijepcima oči otvara. Jahve uspravlja prignute, Jahve ljubi pravedne."},{"v":9,"t":"Jahve štiti tuđince, sirote i udovice podupire, a grešnicima mrsi putove."},{"v":10,"t":"Jahve će kraljevati dovijeka, tvoj Bog, Sione, od koljena do koljena. Aleluja!"}]},"147":{"hr":[{"v":1,"t":"Aleluja! Hvalite Jahvu jer je dobar, pjevajte Bogu našem jer je sladak; svake hvale on je dostojan!"},{"v":2,"t":"Jahve gradi Jeruzalem, sabire raspršene Izraelce."},{"v":3,"t":"On liječi one koji su srca skršena i povija rane njihove."},{"v":4,"t":"On određuje broj zvijezda, svaku njezinim imenom naziva."},{"v":5,"t":"Velik je naš Gospodin i svesilan, nema mjere mudrosti njegovoj."},{"v":6,"t":"Jahve pridiže ponizne, zlotvore do zemlje snizuje."},{"v":7,"t":"Pjevajte Jahvi pjesmu zahvalnu, svirajte na citari Bogu našem!"},{"v":8,"t":"Oblacima on prekriva nebesa i zemlji kišu sprema; daje da po bregovima raste trava i bilje na službu čovjeku."},{"v":9,"t":"On stoci hranu daje i mladim gavranima kada grakću."},{"v":10,"t":"Za konjsku snagu on ne mari nit' mu se mile bedra čovječja."},{"v":11,"t":"Mili su Jahvi oni koji se njega boje, koji se uzdaju u dobrotu njegovu."},{"v":12,"t":"Slavi Jahvu, Jeruzaleme, hvali Boga svoga, Sione!"},{"v":13,"t":"On učvrsti zasune vrata tvojih, blagoslovi u tebi tvoje sinove."},{"v":14,"t":"On dade mir granicama tvojim, pšenicom te hrani najboljom."},{"v":15,"t":"Besjedu svoju šalje na zemlju, brzo trči riječ njegova."},{"v":16,"t":"Kao vunu snijeg razbacuje, prosipa mraz poput pepela."},{"v":17,"t":"On sipa grÓad kao zalogaje, voda mrzne od njegove studeni."},{"v":18,"t":"Riječ svoju pošalje i vode se tope; dunu vjetrom i vode otječu."},{"v":19,"t":"Riječ svoju on objavi Jakovu, odluke svoje i zakone Izraelu."},{"v":20,"t":"Ne učini tako nijednom narodu: nijednom naredbe svoje ne objavi! Aleluja!"}]},"148":{"hr":[{"v":1,"t":"Aleluja! Hvalite Jahvu s nebesa, hvalite ga u visinama!"},{"v":2,"t":"Hvalite ga, svi anđeli njegovi, hvalite ga, sve vojske njegove!"},{"v":3,"t":"Hvalite ga, sunce i mjeseče, hvalite ga, sve zvijezde svjetlosne!"},{"v":4,"t":"Hvalite ga, nebesa nebeska, i vode nad svodom nebeskim!"},{"v":5,"t":"Neka hvale ime Jahvino jer on zapovjedi i postadoše."},{"v":6,"t":"Postavi ih zauvijek i dovijeka po zakonu koji neće proći."},{"v":7,"t":"Hvalite Jahvu sa zemlje, nemani morske i svi bezdani!"},{"v":8,"t":"Ognju i grÓade, sniježe i maglo, olujni vjetre, što riječ njegovu izvršavaš!"},{"v":9,"t":"Gore i svi brežuljci, plodonosna stabla i svi cedrovi!"},{"v":10,"t":"Zvijeri i sve životinje, gmizavci i ptice krilate!"},{"v":11,"t":"Zemaljski kraljevi i svi narodi, knezovi i suci zemaljski!"},{"v":12,"t":"Mladići i djevojke, starci s djecom zajedno:"},{"v":13,"t":"nek' svi hvale ime Jahvino, jer jedino je njegovo ime uzvišeno! Njegovo veličanstvo zemlju i nebo nadvisuje,"},{"v":14,"t":"on podiže snagu svom narodu, on proslavlja svete svoje, sinove Izraelove - narod njemu blizak. Aleluja!"}]},"149":{"hr":[{"v":1,"t":"Aleluja! Pjevajte Jahvi pjesmu novu i u zboru svetih hvalu njegovu!"},{"v":2,"t":"Nek' se raduje Izrael Stvoritelju svojem! Kralju svom neka klikću sinovi Siona!"},{"v":3,"t":"Neka u kolu hvale ime njegovo, bubnjem i citarom neka ga slave!"},{"v":4,"t":"Jer Jahve ljubi narod svoj, spasenjem ovjenčava ponizne!"},{"v":5,"t":"Neka se sveti raduju u slavi, neka kliču s ležaja svojih!"},{"v":6,"t":"Nek' im pohvale Božje budu na ustima, mačevi dvosjekli u rukama"},{"v":7,"t":"da nad pucima izvrše odmazdu i kaznu nad narodima;"},{"v":8,"t":"da im kraljeve bace u lance, a odličnike u okove gvozdene;"},{"v":9,"t":"da na njima izvrše sud davno napisan - nek' bude na čast svim svetima njegovim! Aleluja!"}]},"150":{"hr":[{"v":1,"t":"Aleluja!"},{"v":2,"t":"Hvalite Boga u Svetištu njegovu, slavite ga u veličanstvu svoda nebeskog!"},{"v":3,"t":"Hvalite ga zbog silnih djela njegovih, slavite ga zbog beskrajne veličine njegove!"},{"v":4,"t":"Hvalite ga zvucima roga, slavite ga harfom i citarom!"},{"v":5,"t":"Hvalite ga igrom i bubnjem, slavite ga glazbalima zvonkim i frulom! Hvalite ga cimbalima zvučnim, slavite ga cimbalima gromkim!"},{"v":6,"t":"Sve što god diše Jahvu neka slavi! Aleluja!"}]}},"PRO":{"1":{"hr":[{"v":1,"t":"Mudre izreke Salomona, sina Davidova, kralja izraelskog:"},{"v":2,"t":"da se spozna mudrost i pouka, da se shvate razumne riječi;"},{"v":3,"t":"da se primi umna pouka, pravda i pravica i nepristranost;"},{"v":4,"t":"da se dade pamet neiskusnima, mladiću znanje i umijeće;"},{"v":5,"t":"kad mudar čuje, da umnoži znanje, a razuman steče mudrije misli;"},{"v":6,"t":"da razumije izreke i prispodobe, riječi mudraca i njihove zagonetke."},{"v":7,"t":"Strah je Gospodnji početak spoznaje, ali ludi preziru mudrost i pouku."},{"v":8,"t":"Poslušaj, sine moj, pouku oca svoga i ne odbacuj naputka svoje majke!"},{"v":9,"t":"Jer će ti biti ljupki vijenac na glavi i ogrlica oko tvoga vrata."},{"v":10,"t":"Sine moj, ako te grešnici mame, ne pristaj;"},{"v":11,"t":"ako bi rekli: “Hodi s nama, da vrebamo krv, čekamo u zasjedi nevina ni za što;"},{"v":12,"t":"da ih progutamo žive kao carstvo smrti i cijele kao one koji silaze u grob;"},{"v":13,"t":"naplijenit ćemo svakojaka blaga, napuniti svoje kuće plijenom;"},{"v":14,"t":"bacat ćeš s nama svoj ždrijeb, svi ćemo zajedno imati jednu kesu.”"},{"v":15,"t":"Sine moj, ne idi s njima na put, makni nogu od njihove staze."},{"v":16,"t":"Jer na zlo trče svojim nogama i hite prolijevati krv."},{"v":17,"t":"Jer uzalud je razapinjati mrežu pred očima svima pticama."},{"v":18,"t":"A oni vrebaju vlastitu krv, postavljaju zasjedu svojemu životu."},{"v":19,"t":"Takva je sudba svih lakomih na ružan dobitak: on ih života stane."},{"v":20,"t":"Mudrost glasno uzvikuje na ulici, na trgovima diže svoj glas;"},{"v":21,"t":"propovijeda po bučnim uglovima, na otvorenim gradskim vratima govori svoje riječi:"},{"v":22,"t":"“Dokle ćete, vi glupi, ljubiti glupost i dokle će podsmjevačima biti milo podsmijevanje, i dokle će bezumnici mrziti znanje?"},{"v":23,"t":"Poslušajte moju opomenu! Gle, svoj duh pred vas izlijevam, hoću vas poučiti svojim riječima."},{"v":24,"t":"Koliko sam vas zvala, a vi ste odbijali; pružala sam ruku, ali je nitko ne opazi."},{"v":25,"t":"Nego ste odbacili svaki moj savjet i niste poslušali moje opomene;"},{"v":26,"t":"zato ću se i ja smijati vašoj propasti, rugat ću se kad vas obuzme tjeskoba:"},{"v":27,"t":"kad navali na vas strah kao nevrijeme i zgrabi vas propast kao vihor, kad navali na vas nevolja i muka."},{"v":28,"t":"Tada će me zvati, ali se ja neću odazvati; tražit će me, ali me neće naći."},{"v":29,"t":"Jer su mrzili spoznaju i nisu izabrali Gospodnjeg straha"},{"v":30,"t":"niti su poslušali moj savjet, nego su prezreli svaku moju opomenu."},{"v":31,"t":"Zato će jesti plod svojeg vladanja i nasititi se vlastitih savjeta."},{"v":32,"t":"Jer glupe će ubiti njihovo odbijanje, a nemar će upropastiti bezumne."},{"v":33,"t":"A tko sluša mene, bezbrižan ostaje i spokojno živi bez straha od zla.”"}]},"2":{"hr":[{"v":1,"t":"Sine moj, ako primiš moje riječi i pohraniš u sebi moje zapovijedi,"},{"v":2,"t":"i uhom svojim osluhneš mudrost i obratiš svoje srce razboru;"},{"v":3,"t":"jest, ako prizoveš razum i zavapiš za razborom;"},{"v":4,"t":"ako ga potražiš kao srebro i tragaš za njim kao za skrivenim blagom -"},{"v":5,"t":"tada ćeš shvatiti strah Gospodnji i naći ćeš Božje znanje."},{"v":6,"t":"Jer Jahve daje mudrost, iz njegovih usta dolazi znanje i razboritost."},{"v":7,"t":"On pravednicima pruža svoju pomoć, štit je onih koji hode u bezazlenosti."},{"v":8,"t":"Jer on štiti staze pravde i čuva pute svojih pobožnika."},{"v":9,"t":"Tada ćeš shvatiti pravdu, pravicu, pravednost i sve staze dobra,"},{"v":10,"t":"jer će mudrost ući u tvoje srce i spoznaja će obradovati tvoju dušu."},{"v":11,"t":"Oprez će paziti na te i razboritost će te čuvati:"},{"v":12,"t":"da te izbavi od zla puta, od varava čovjeka,"},{"v":13,"t":"od onih koji ostavljaju staze poštenja te idu mračnim putovima;"},{"v":14,"t":"koji se vesele čineći zlo i likuju u opačinama zloće;"},{"v":15,"t":"kojih su staze krive i koji su opaki na svojim putovima;"},{"v":16,"t":"da te izbavi od preljubnice i od tuđinke koja laska riječima;"},{"v":17,"t":"koja ostavlja prijatelja svoje mladosti i zaboravlja zavjet svoga Boga"},{"v":18,"t":"jer joj kuća tone u smrt i njezini putovi vode mrtvima."},{"v":19,"t":"Tko god zalazi k njoj ne vraća se nikad i ne nalazi više putove života."},{"v":20,"t":"Zato idi putem čestitih i drži se staza pravedničkih!"},{"v":21,"t":"Jer samo će pravedni nastavati zemlju i bezazleni će ostati na njoj."},{"v":22,"t":"A opake će zbrisati sa zemlje i bogohulnike iščupati iz nje."}]},"3":{"hr":[{"v":1,"t":"Sine moj, ne zaboravljaj moje pouke, i tvoje srce neka čuva moje zapovijedi,"},{"v":2,"t":"jer će ti produljiti dane i životne godine i podariti spokojstvo."},{"v":3,"t":"Neka te ne ostavljaju dobrota i vjernost, objesi ih sebi oko vrata, upiši ih na ploču srca svoga."},{"v":4,"t":"Tako ćeš steći ugled i uspjeti pred Božjim i ljudskim očima."},{"v":5,"t":"Uzdaj se u Jahvu svim srcem i ne oslanjaj se na vlastiti razbor."},{"v":6,"t":"Misli na nj na svim svojim putovima i on će ispraviti tvoje staze."},{"v":7,"t":"Ne umišljaj da si mudar: boj se Jahve i kloni se zla."},{"v":8,"t":"To će biti lijek tvome tijelu i okrepa tvojim kostima."},{"v":9,"t":"Časti Jahvu svojim blagom i prvinama svega svojeg prirasta."},{"v":10,"t":"I tvoje će žitnice biti prepune i tvoje će se kace prelijevati novim vinom."},{"v":11,"t":"Sine moj, ne odbacuj Jahvine opomene i nemoj da ti omrzne njegov ukor."},{"v":12,"t":"Jer koga Jahve ljubi onoga i kori, kao otac sina koga voli."},{"v":13,"t":"Blago čovjeku koji je stekao mudrost i čovjeku koji je zadobio razboritost."},{"v":14,"t":"Jer bolje je steći nju nego steći srebro, i veći je dobitak ona i od zlata."},{"v":15,"t":"Skupocjenija je od bisera, i što je god tvojih dragocjenosti, s njome se porediti ne mogu;"},{"v":16,"t":"dug joj je život u desnoj ruci, a u lijevoj bogatstvo i čast."},{"v":17,"t":"Njezini su putovi putovi miline i sve su njene staze pune spokoja."},{"v":18,"t":"Životno je drvo onima koji se nje drže i sretan je onaj tko je zadrži."},{"v":19,"t":"Jahve je mudrošću utemeljio zemlju i umom utvrdio nebesa;"},{"v":20,"t":"njegovim su se znanjem otvorili bezdani i oblaci osuli rosom."},{"v":21,"t":"Sine moj, ne gubi to iz očiju, sačuvaj razbor i oprez."},{"v":22,"t":"I bit će život tvojoj duši i ures vratu tvome."},{"v":23,"t":"Bez straha ćeš tada kročiti svojim putem i noga ti se neće spoticati."},{"v":24,"t":"Kad legneš, nećeš se plašiti, i kad zaspiš, slatko ćeš snivati."},{"v":25,"t":"Ne boj se nenadne strahote ni nagle propasti kad stigne bezbožnike."},{"v":26,"t":"Jer će ti Jahve biti uzdanje i čuvat će nogu tvoju od zamke."},{"v":27,"t":"Ne uskrati dobročinstva potrebitim kad god to možeš učiniti."},{"v":28,"t":"Ne reci svome bližnjemu: “Idi i dođi opet, sjutra ću ti dati”, kad možeš već sada."},{"v":29,"t":"Ne kuj zla svome bližnjemu dok on bez straha kod tebe boravi."},{"v":30,"t":"Ne pravdaj se ni s kim bez razloga ako ti nije učinio nikakva zla."},{"v":31,"t":"Nemoj zavidjeti nasilniku niti slijediti njegove pute,"},{"v":32,"t":"jer su Jahvi mrski pokvarenjaci, a prisan je s pravednima."},{"v":33,"t":"Jahvino je prokletstvo na domu bezbožnika, a blagoslov u stanu pravednika."},{"v":34,"t":"S podsmjevačima on se podsmijeva, a poniznima dariva milost."},{"v":35,"t":"Mudri će baštiniti čast, a bezumnici snositi sramotu."}]},"4":{"hr":[{"v":1,"t":"Slušajte, djeco, pouku očevu i pazite kako biste spoznali mudrost,"},{"v":2,"t":"jer dobar vam nauk dajem: ne prezrite moga naputka."},{"v":3,"t":"I ja sam bio sin u svoga oca i nježan jedinac u svoje matere;"},{"v":4,"t":"i mene je on učio i govorio mi: “Zadrži moje riječi u svojem srcu, poštuj moje zapovijedi i živjet ćeš."},{"v":5,"t":"Steci mudrost, steci razbor, ne smeći ih s uma i ne odstupi od riječi mojih usta."},{"v":6,"t":"Ne ostavljaj je i čuvat će te; ljubi je i obranit će te."},{"v":7,"t":"Početak je mudrosti: steci sebi mudrost i svim svojim imanjem steci razboritost."},{"v":8,"t":"Veličaj je i uzvisit će te; donijet će ti čast kad je prigrliš."},{"v":9,"t":"Stavit će ti ljupki vijenac na glavu, i obdarit će te krasnom krunom.”"},{"v":10,"t":"Poslušaj, sine moj, primi moje riječi i umnožit će se godine tvojeg života."},{"v":11,"t":"Poučih te putu mudrosti, navratih te na prave staze;"},{"v":12,"t":"neće ti se zapletati koraci kad staneš hoditi; potrčiš li, nećeš posrnuti."},{"v":13,"t":"Čvrsto se drži pouke, ne puštaj je, čuvaj je, jer ona ti je život."},{"v":14,"t":"Ne idi stazom opakih i ne stupaj putem zlikovaca."},{"v":15,"t":"Ostavi ga, ne hodi njime; kloni ga se i zaobiđi ga."},{"v":16,"t":"Jer oni ne spavaju ako ne učine zla, i san im ne dolazi ako koga ne obore."},{"v":17,"t":"Jer jedu kruh opačine i piju vino nasilja."},{"v":18,"t":"A pravednička je staza kao svjetlost svanuća, koja je sve jasnija do potpunog dana."},{"v":19,"t":"A put je opakih kao mrkli mrak: ne znaju o što će se spotaknuti."},{"v":20,"t":"Sine moj, pazi na moje riječi, prigni uho svoje mojim besjedama."},{"v":21,"t":"Ne gubi ih nikad iz očiju, pohrani ih usred srca svoga."},{"v":22,"t":"Jer su život onima koji ih nalaze i ozdravljenje svemu tijelu njihovu."},{"v":23,"t":"A svrh svega, čuvaj svoje srce, jer iz njega izvire život."},{"v":24,"t":"Drži daleko od sebe lažna usta i udalji od sebe usne prijevarne."},{"v":25,"t":"Nek' tvoje oči gledaju u lice i neka ti je pogled uvijek prav."},{"v":26,"t":"Pazi na stazu kojom kročiš i neka ti svi putovi budu pouzdani."},{"v":27,"t":"Ne skreći ni desno ni lijevo, drži svoj korak daleko oda zla."}]},"5":{"hr":[{"v":1,"t":"Sine moj, čuj moju mudrost, prigni uho mojoj razboritosti"},{"v":2,"t":"da sačuvaš oprez, da ti usne zadrže znanje."},{"v":3,"t":"Jer s usana žene preljubnice kaplje med i nepce joj je glađe od ulja,"},{"v":4,"t":"ali je ona naposljetku gorka kao pelin, oštra kao dvosjekli mač."},{"v":5,"t":"Njene noge silaze k smrti, a koraci vode u Podzemlje."},{"v":6,"t":"Ona ne pazi na put života, ne mari što su joj staze kolebljive."},{"v":7,"t":"Zato me sada poslušaj, sine, i ne odstupaj od riječi mojih usta."},{"v":8,"t":"Neka je put tvoj daleko od nje i ne približuj se vratima njezine kuće,"},{"v":9,"t":"da drugima ne bi dao svoju slavu i okrutnima svoje godine;"},{"v":10,"t":"da se ne bi tuđinci nasitili tvoga dobra i da tvoja zaslužba ne ode u tuđu kuću;"},{"v":11,"t":"da ne ridaš na koncu kad ti nestane tijela i puti"},{"v":12,"t":"i da ne kažeš: “Oh, kako sam mrzio pouku i kako mi je srce preziralo ukor!"},{"v":13,"t":"I ne slušah glasa svojih učitelja, niti priklonih uho onima što me poučavahu."},{"v":14,"t":"I umalo ne zapadoh u svako zlo, usred zbora i zajednice!”"},{"v":15,"t":"Pij vodu iz svoje nakapnice i onu što teče iz tvoga studenca."},{"v":16,"t":"Moraju li se tvoji izvori razlijevati i tvoji potoci teći ulicama?"},{"v":17,"t":"Nego neka oni budu samo tvoji, a ne i tuđinaca koji su uza te."},{"v":18,"t":"Neka je blagoslovljen izvor tvoj i raduj se sa ženom svoje mladosti:"},{"v":19,"t":"neka ti je kao mila košuta i ljupka gazela, neka te grudi njene opajaju u svako doba, njezina ljubav zatravljuje bez prestanka!"},{"v":20,"t":"TÓa zašto bi se, sine moj, zanosio preljubnicom i grlio tuđinki njedra?"},{"v":21,"t":"Jer pred Jahvinim su očima čovjekovi putovi i on motri sve njegove staze."},{"v":22,"t":"Opakoga će uhvatiti njegova zloća i sapet će ga užad njegovih grijeha."},{"v":23,"t":"Umrijet će jer nema pouke, propast će zbog svoje goleme gluposti."}]},"6":{"hr":[{"v":1,"t":"Sine moj, kad jamčiš bližnjemu svojem i daš svoju ruku drugome,"},{"v":2,"t":"vezao si se vlastitim usnama, uhvatio se riječima svojih usta;"},{"v":3,"t":"učini onda ovo, sine moj: oslobodi se! Jer si dopao u ruke bližnjemu svojemu; idi, baci se preda nj i salijeći bližnjega svoga."},{"v":4,"t":"Ne daj sna svojim očima ni drijema svojim vjeđama;"},{"v":5,"t":"otmi se kao gazela iz mreže i kao ptica iz ruku ptičaru."},{"v":6,"t":"Idi k mravu, lijenčino, promatraj njegove pute i budi mudar:"},{"v":7,"t":"on nema vođe, nadzornika, ni nadstojnika,"},{"v":8,"t":"ljeti se sebi brine za hranu i prikuplja jelo u doba žetve."},{"v":9,"t":"A ti, dokle ćeš, lijenčino, spavati? Kad ćeš se dići oda sna svoga?"},{"v":10,"t":"Još malo odspavaj, još malo odrijemaj, još malo podvij ruke za počinak"},{"v":11,"t":"i doći će tvoje siromaštvo kao skitač i tvoja oskudica kao oružanik."},{"v":12,"t":"Nevaljalac i opak čovjek hodi s lažljivim ustima;"},{"v":13,"t":"namiguje očima, lupka nogama, pokazuje prstima;"},{"v":14,"t":"prijevare su mu u srcu, snuje zlo u svako doba, zameće svađe."},{"v":15,"t":"Zato će mu iznenada doći propast, i učas će se slomiti i neće mu biti lijeka."},{"v":16,"t":"Šest je stvari koje Gospod mrzi, a sedam ih je gnusoba njegovu biću:"},{"v":17,"t":"ohole oči, lažljiv jezik, ruke koje prolijevaju krv nevinu,"},{"v":18,"t":"srce koje smišlja grešne misli, noge koje hitaju na zlo,"},{"v":19,"t":"lažan svjedok koji širi laži, i čovjek koji zameće svađe među braćom."},{"v":20,"t":"Sine moj, čuvaj zapovijedi oca svoga i ne odbacuj nauka matere svoje."},{"v":21,"t":"Priveži ih sebi na srce zauvijek, ovij ih oko svoga grla;"},{"v":22,"t":"da te vode kada hodiš, da te čuvaju kada spavaš i da te razgovaraju kad se probudiš."},{"v":23,"t":"Jer je zapovijed svjetiljka, pouka je svjetlost, opomene stege put su života;"},{"v":24,"t":"da te čuvaju od zle žene, od laskava jezika tuđinke."},{"v":25,"t":"Ne poželi u svom srcu njezine ljepote i ne daj da te osvoji trepavicama svojim,"},{"v":26,"t":"jer bludnici dostaje i komad kruha, dok preljubnica lovi dragocjeni život."},{"v":27,"t":"Može li tko nositi oganj u njedrima a da mu se odjeća ne upali?"},{"v":28,"t":"Može li tko hoditi po živom ugljevlju a svojih nogu da ne ožeže?"},{"v":29,"t":"Tako biva onomu tko ide k ženi svoga bližnjega: neće ostati bez kazne tko god se nje dotakne."},{"v":30,"t":"Ne sramote li lupeža sve ako je krao da gladan utoli glad:"},{"v":31,"t":"uhvaćen, on sedmerostruko vraća i plaća svim imanjem kuće svoje."},{"v":32,"t":"Nerazuman je, dakle, tko se upušta s preljubnicom; dušu svoju gubi koji tako čini."},{"v":33,"t":"Bruke i sramote dopada i rug mu se nikad ne briše."},{"v":34,"t":"Jer bijesna je ljubomornost u muža: on ne zna za milost u osvetni dan;"},{"v":35,"t":"ne pristaje ni na kakav otkup i ne prima ma kolike mu darove dao."}]},"7":{"hr":[{"v":1,"t":"Čuvaj, sine, riječi moje i pohrani moje zapovijedi kod sebe."},{"v":2,"t":"Čuvaj moje zapovijedi, i bit ćeš živ, i nauk moj kao zjenicu oka svoga."},{"v":3,"t":"Priveži ih sebi na prste, upiši ih na ploči srca svoga;"},{"v":4,"t":"reci mudrosti: “Moja si sestra” i razboritost nazovi “sestričnom”,"},{"v":5,"t":"da te čuva od žene preljubnice, od tuđinke koja laskavo govori."},{"v":6,"t":"Kad bijah jednom na prozoru svoje kuće i gledah van kroz rešetku,"},{"v":7,"t":"vidjeh među lakovjernima, opazih među momcima nerazumna mladića:"},{"v":8,"t":"prolazio je ulicom kraj njezina ugla i koracao putem k njezinoj kući"},{"v":9,"t":"u sumraku između dana i večeri kad se hvata noćna tmina;"},{"v":10,"t":"i gle, susrete ga žena, bludno odjevena i s prijevarom u srcu."},{"v":11,"t":"Jogunasta bijaše i razuzdana, noge joj se nisu mogle u kući zadržati;"},{"v":12,"t":"bila je čas na ulici, čas na trgovima i vrebala kod svakog ugla;"},{"v":13,"t":"i uhvati ga i poljubi i reče mu bezobrazna lica:"},{"v":14,"t":"“Bila sam dužna žrtvu pričesnicu, i danas izvrših svoj zavjet;"},{"v":15,"t":"zato sam ti izašla u susret, da te tražim, i nađoh te."},{"v":16,"t":"Svoju sam postelju nastrla sagovima, vezenim pokrivačima misirskim;"},{"v":17,"t":"svoj sam krevet namirisala smirnom, alojem i cimetom."},{"v":18,"t":"Hajde da se opijamo nasladom do jutra i da se radujemo užicima ljubavi."},{"v":19,"t":"Jer muža mi nema kod kuće: otišao je na dalek put;"},{"v":20,"t":"uzeo je sa sobom novčani tobolac; a vratit će se kući tek o uštapu.”"},{"v":21,"t":"Tako ga zavede svojim vičnim nagovorom, odvuče ga svojim glatkim usnama."},{"v":22,"t":"I ludo on pođe za njom, kao što vol ide na klaonicu i kao što jelen zapleten u mrežu čeka"},{"v":23,"t":"dok mu strijela ne probije jetra, i kao ptica što ulijeće u zamku, i ne znajući da će ga to života stajati."},{"v":24,"t":"Zato me, sine moj, poslušaj i čuj riječi mojih usta."},{"v":25,"t":"Nek' ti srce ne zastranjuje na njezine putove i ne lutaj po njezinim stazama."},{"v":26,"t":"Jer je mnoge smrtno ranila i oborila, i mnogo je onih što ih je pobila."},{"v":27,"t":"U Podzemlje vode putovi kroz njenu kuću, dolje u odaje smrti."}]},"8":{"hr":[{"v":1,"t":"Ne propovijeda li mudrost i ne diže li razboritost svoj glas?"},{"v":2,"t":"Navrh brda, uza cestu, na raskršćima stoji,"},{"v":3,"t":"kod izlaza iz grada, kraj ulaznih vrata, ona glasno viče:"},{"v":4,"t":"“Vama, o ljudi, propovijedam i upravljam svoj glas sinovima ljudskim."},{"v":5,"t":"Shvatite mudrost, vi neiskusni, a vi nerazumni, urazumite srce."},{"v":6,"t":"Slušajte, jer ću zboriti o važnim stvarima, i moje će usne otkriti što je pravo."},{"v":7,"t":"Jer moje nepce zbori istinu i zloća je mojim usnama mrska."},{"v":8,"t":"Sve su riječi mojih usta pravične, u njima nema ništa ni krivo ni prijetvorno."},{"v":9,"t":"Sve su one jasne razboritomu i pravedne onomu tko je stekao spoznaju."},{"v":10,"t":"Primajte radije moju pouku no srebro i znanje požudnije od zlata."},{"v":11,"t":"Jer mudrost je vrednija od biserja i nikakve se dragocjenosti ne mogu porediti s njom."},{"v":12,"t":"Ja, mudrost, boravim s razboritošću i posjedujem znanje umna djelovanja."},{"v":13,"t":"Strah Gospodnji mržnja je na zlo. Oholost, samodostatnost, put zloće i usta puna laži - to ja mrzim."},{"v":14,"t":"Moji su savjet i razboritost, ja sam razbor i moja je jakost."},{"v":15,"t":"Po meni kraljevi kraljuju i velikaši dijele pravdu."},{"v":16,"t":"Po meni knezuju knezovi i odličnici i svi suci zemaljski."},{"v":17,"t":"Ja ljubim one koji ljube mene i nalaze me koji me traže."},{"v":18,"t":"U mene je bogatstvo i slava, postojano dobro i pravednost."},{"v":19,"t":"Moj je plod bolji od čista i žežena zlata i moj je prihod bolji od čistoga srebra."},{"v":20,"t":"Ja kročim putem pravde, sred pravičnih staza,"},{"v":21,"t":"da dadem dobra onima koji me ljube i napunim njihove riznice."},{"v":22,"t":"Jahve me stvori kao počelo svoga djela, kao najraniji od svojih čina, u pradoba;"},{"v":23,"t":"oblikovana sam još od vječnosti, odiskona, prije nastanka zemlje."},{"v":24,"t":"Rodih se kad još nije bilo pradubina, dok nije bilo izvora obilnih voda."},{"v":25,"t":"Rodih se prije nego su utemeljene gore, prije brežuljaka."},{"v":26,"t":"Kad još ne bijaše načinio zemlje, ni poljana, ni početka zemaljskom prahu;"},{"v":27,"t":"kad je stvarao nebesa, bila sam nazočna, kad je povlačio krug na licu bezdana."},{"v":28,"t":"Kad je u visini utvrđivao oblake i kad je odredio snagu izvoru pradubina;"},{"v":29,"t":"kad je postavljao moru njegove granice da mu se vode ne preliju preko obala, kad je polagao temelje zemlji,"},{"v":30,"t":"bila sam kraj njega, kao graditeljica, bila u radosti, iz dana u dan, igrajući pred njim sve vrijeme:"},{"v":31,"t":"igrala sam po tlu njegove zemlje, i moja su radost djeca čovjekova."},{"v":32,"t":"Tako, djeco, poslušajte me, blago onima koji čuvaju moje putove."},{"v":33,"t":"Poslušajte pouku - da stečete mudrost i nemojte je odbaciti."},{"v":34,"t":"Blago čovjeku koji me sluša i bdi na mojim vratima svaki dan i koji čuva dovratnike moje."},{"v":35,"t":"Jer tko nalazi mene, nalazi život i stječe milost od Jahve."},{"v":36,"t":"A ako se ogriješi o mene, udi svojoj duši: svi koji mene mrze ljube smrt.”"}]},"9":{"hr":[{"v":1,"t":"Mudrost je sazidala sebi kuću, i otesala sedam stupova."},{"v":2,"t":"Poklala je svoje klanice, pomiješala svoje vino i postavila svoj stol."},{"v":3,"t":"Poslala je svoje djevojke da objave svrh gradskih visina:"},{"v":4,"t":"“Tko je neiskusan, neka se svrati ovamo!” A nerazumnima govori:"},{"v":5,"t":"“Hodite, jedite od mojega kruha i pijte vina koje sam pomiješala."},{"v":6,"t":"Ostavite ludost, da biste živjeli, i hodite putem razboritosti.”"},{"v":7,"t":"Tko poučava podrugljivca, prima pogrdu, i tko prekorava opakoga, prima ljagu."},{"v":8,"t":"Ne kori podsmjevača, da te ne zamrzi; kori mudra, da te zavoli."},{"v":9,"t":"Pouči mudroga, i bit će još mudriji; uputi pravednoga, i uvećat će se njegovo znanje."},{"v":10,"t":"Gospodnji strah početak je mudrosti, a razboritost je spoznaja Presvetog."},{"v":11,"t":"“Po meni ti se umnožavaju dani i množe ti se godine života."},{"v":12,"t":"Ako si mudar, sebi si mudar; budeš li podsmjevač, sam ćeš snositi.”"},{"v":13,"t":"Gospođa ludost puna je strasti, prosta je i ne zna ništa."},{"v":14,"t":"I sjedi na vratima svoje kuće na stolici, u gradskim visinama,"},{"v":15,"t":"te poziva one koji prolaze putem, koji ravno idu svojim stazama:"},{"v":16,"t":"“Tko je neiskusan, neka se svrati ovamo!” I nerazumnomu govori:"},{"v":17,"t":"“Kradena je voda slatka i ugodno je potajno jesti kruh.”"},{"v":18,"t":"A on ne zna da su Sjene ondje, da uzvanici njezini počivaju u Podzemlju."}]},"10":{"hr":[{"v":1,"t":"Mudar sin veseli oca, a lud je sin žalost majci svojoj."},{"v":2,"t":"Ne koristi krivo stečeno blago, dok pravednost izbavlja od smrti."},{"v":3,"t":"Ne dopušta Jahve da gladuje duša pravednika, ali odbija pohlepu opakih."},{"v":4,"t":"Lijena ruka osiromašuje čovjeka, a marljiva ga obogaćuje."},{"v":5,"t":"Tko sabira ljeti, razuman je sin, a tko hrče o žetvi, navlači sramotu."},{"v":6,"t":"Blagoslovi su nad glavom pravedniku, a usta opakih kriju nasilje."},{"v":7,"t":"Pravednikov je spomen blagoslovljen, a opakom se ime proklinje."},{"v":8,"t":"Tko je mudra srca, prima zapovijedi, dok brbljava luda propada."},{"v":9,"t":"Tko nedužno živi, hodi bez straha, a tko ide krivim putovima, poznat će se."},{"v":10,"t":"Tko žmirka okom, zadaje tugu, a tko ludo zbori, propada."},{"v":11,"t":"Pravednikova su usta izvor života, a opakomu usta kriju nasilje."},{"v":12,"t":"Mržnja izaziva svađu, a ljubav pokriva sve pogreške."},{"v":13,"t":"Na usnama razumnoga nalazi se mudrost, a batina je za leđa nerazumna čovjeka."},{"v":14,"t":"Mudri kriju znanje, a luđakova su usta blizu propasti."},{"v":15,"t":"Blago je bogatomu tvrdi grad, a ubogima je propast njihovo siromaštvo."},{"v":16,"t":"Pravednik prirađuje za život, a opaki prirađuje za grijeh."},{"v":17,"t":"Tko se naputka drži, na putu je života, a zabluđuje tko se na ukor ne osvrće."},{"v":18,"t":"Lažljive usne kriju mržnju, a tko klevetu širi, bezuman je!"},{"v":19,"t":"Obilje riječi ne biva bez grijeha, a tko zauzdava svoj jezik, razuman je."},{"v":20,"t":"Pravednikov je jezik odabrano srebro, a razum opakoga malo vrijedi."},{"v":21,"t":"Pravednikove su usne hrana mnogima, a luđaci umiru s ludosti svoje."},{"v":22,"t":"Gospodnji blagoslov obogaćuje i ne prati ga nikakva muka."},{"v":23,"t":"Bezumniku je radost učiniti sramotno djelo, a razumnu čovjeku biti mudar."},{"v":24,"t":"Čega se opaki boji, ono će ga stići, a pravednička se želja ispunjava."},{"v":25,"t":"Kad oluja prohuja, opakoga nestane, a pravednik ima temelj vječni."},{"v":26,"t":"Kakav je ocat zubima i dim očima, takav je ljenivac onima koji ga šalju."},{"v":27,"t":"Strah Gospodnji umnaža dane, a opakima se prekraćuju godine."},{"v":28,"t":"Pravedničko je ufanje puno radosti, a opakima je nada uprazno."},{"v":29,"t":"Gospodnji je put okrilje bezazlenu, a propast onima koji čine zlo."},{"v":30,"t":"Pravednik se neće nikad pokolebati, a opakih će nestati s lica zemlje."},{"v":31,"t":"Pravednikova usta rađaju mudrošću, a opak jezik čupa se s korijenom."},{"v":32,"t":"Pravednikove usne znaju što je milo, dok usta opakih poznaju zloću."}]},"11":{"hr":[{"v":1,"t":"Lažna je mjera mrska Jahvi, a puna mjera mila mu je."},{"v":2,"t":"S ohološću dolazi sramota, a u smjernih je mudrost."},{"v":3,"t":"Pravednike vodi nevinost njihova, a bezbožnike upropašćuje njihova opačina."},{"v":4,"t":"Ne pomaže bogatstvo u dan Božje srdžbe, a pravednost izbavlja od smrti."},{"v":5,"t":"Nedužnomu pravda njegova put utire, a zao propada od svoje zloće."},{"v":6,"t":"Poštene izbavlja pravda njihova, a bezbožnici se hvataju u svoju lakomost."},{"v":7,"t":"Kad zao čovjek umre, nada propada i ufanje u imetak ruši se."},{"v":8,"t":"Pravednik se od tjeskobe izbavlja, a opaki dolazi na mjesto njegovo."},{"v":9,"t":"Bezbožnik ustima ubija svoga bližnjega, a pravednici se izbavljaju znanjem."},{"v":10,"t":"Sa sreće pravedničke grad se raduje i klikuje zbog propasti opakoga."},{"v":11,"t":"Blagoslovom pravednika grad se diže, a ustima opakih razara se."},{"v":12,"t":"Nerazumnik prezire svoga bližnjega, dok čovjek uman šuti."},{"v":13,"t":"Tko s klevetom hodi, otkriva tajnu, a čovjek pouzdana duha čuva se."},{"v":14,"t":"Gdje vodstva nema, narod propada, jer spasenje je u mnogim savjetnicima."},{"v":15,"t":"Veoma zlo prolazi tko jamči za drugoga, a bez straha je tko mrzi na jamstvo."},{"v":16,"t":"Ljupka žena stječe slavu, a krepki muževi bogatstvo."},{"v":17,"t":"Dobrostiv čovjek sam sebi dobro čini, a okrutnik muči vlastito tijelo."},{"v":18,"t":"Opak čovjek pribavlja isprazan dobitak, a tko sije pravdu, ima sigurnu nagradu."},{"v":19,"t":"Tko je čvrst u pravednosti, ide u život, a tko za zlom trči, na smrt mu je."},{"v":20,"t":"Mrski su Jahvi srcem opaki, a mili su mu životom savršeni."},{"v":21,"t":"Zaista, zao čovjek neće proći bez kazne, a rod će se pravednički izbaviti."},{"v":22,"t":"Zlatan je kolut na rilu svinjskom: žena lijepa, a bez razuma."},{"v":23,"t":"Pravednička je želja samo na sreću, a nada je opakih prolazna."},{"v":24,"t":"Tko dijeli obilato, sve više ima, a tko škrtari, sve je siromašniji."},{"v":25,"t":"Podašna duša nalazi okrepu, i tko napaja druge, sam će se napojiti."},{"v":26,"t":"Tko ne da žita, kune ga narod, a blagoslov je nad glavom onoga koji ga prodaje."},{"v":27,"t":"Tko traži dobro, nalazi milost, a tko za zlom ide, ono će ga snaći."},{"v":28,"t":"Tko se uzda u bogatstvo, propada, a pravednici uspijevaju kao zeleno lišće."},{"v":29,"t":"Tko vlastitu kuću zapusti, vjetar žanje, a luđak je sluga mudromu."},{"v":30,"t":"Plod je pravednikov drvo života, i mudrac je tko predobiva žive duše."},{"v":31,"t":"Ako se pravedniku plaća na zemlji, još će se više opakomu i grešniku."}]},"12":{"hr":[{"v":1,"t":"Tko ljubi pouku, ljubi znanje, a tko mrzi ukor, lud je."},{"v":2,"t":"Dobar dobiva milost od Jahve, a podmukao osudu."},{"v":3,"t":"Zloćom se čovjek ne utvrđuje, a korijen se pravedniku ne pomiče."},{"v":4,"t":"Kreposna je žena vijenac mužu svojemu, a sramotna mu je kao gnjilež u kostima."},{"v":5,"t":"Pravedničke su misli pravične, spletke opakih prijevarne."},{"v":6,"t":"Riječi opakih pogubne su zamke, a pravedne izbavljaju usta njihova."},{"v":7,"t":"Opaki se ruše i nema ih više, a kuća pravednika ostaje."},{"v":8,"t":"Čovjek se hvali po oštrini svoga razuma, a prezire se tko je opak srcem."},{"v":9,"t":"Bolje je biti malen i imati samo jednog slugu nego se hvastati a nemati ni kruha."},{"v":10,"t":"Pravednik pazi i na život svog živinčeta, dok je opakomu srce okrutno."},{"v":11,"t":"Tko obrađuje svoju zemlju, sit je kruha, a tko trči za ništavilom, nerazuman je."},{"v":12,"t":"Čežnja je opakoga mreža od zala, a korijen pravednika daje ploda."},{"v":13,"t":"Opakomu je zamka grijeh njegovih usana, a pravednik se izbavlja od tjeskobe."},{"v":14,"t":"Od ploda svojih usta nasitit će se svatko obilno, a ono što je rukama učinio vratit će mu se."},{"v":15,"t":"Luđaku se čini pravim njegov put, a mudar čovjek sluša savjete."},{"v":16,"t":"Luđak odmah odaje svoj bijes, a pametan pokriva sramotu."},{"v":17,"t":"Tko govori istinu, otkriva što je pravo, a lažljiv svjedok prijevaru."},{"v":18,"t":"Nesmotren govori kao da mačem probada, a jezik je mudrih iscjeljenje."},{"v":19,"t":"Istinita usta traju dovijeka, a lažljiv jezik samo za čas."},{"v":20,"t":"Prijevara je u srcu onih koji snuju zlo, a veselje u onih koji dijele miroljubive savjete."},{"v":21,"t":"Pravednika ne stiže nikakva nevolja, a opaki u zlu grcaju."},{"v":22,"t":"Mrske su Jahvi usne lažljive, a mili su mu koji zbore istinu."},{"v":23,"t":"Promišljen čovjek prikriva svoje znanje, a srce bezumničko razglašuje svoju ludost."},{"v":24,"t":"Marljiva ruka vlada, a nemar vodi u podložnost."},{"v":25,"t":"Briga u srcu pritiskuje čovjeka, a blaga riječ veseli ga."},{"v":26,"t":"Pravednik vodi svojeg prijatelja, a opake zavodi njihov put."},{"v":27,"t":"Nemaran ne ulovi svoje lovine, a marljivost je čovjeku blago dragocjeno."},{"v":28,"t":"Na stazi pravice stoji život i na njezinu putu nema smrti."}]},"13":{"hr":[{"v":1,"t":"Mudar sin sluša naputak očev, a podsmjevač ne sluša ukora."},{"v":2,"t":"Od ploda usta svojih uživa čovjek sreću, a srce je nevjernika puno nasilja."},{"v":3,"t":"Tko čuva usta svoja, čuva život svoj, a tko nesmotreno zbori, o glavu mu je."},{"v":4,"t":"Uzaludna je žudnja lijenčine, a ispunit će se želja marljivih."},{"v":5,"t":"Pravednik mrzi na lažljivu riječ, a opaki goji mržnju i sramotu."},{"v":6,"t":"Pravda čuva pobožna, a opake grijeh obara."},{"v":7,"t":"Netko se gradi bogatim, a ništa nema, netko se gradi siromašnim, a ima veliko bogatstvo."},{"v":8,"t":"Otkup života bogatstvo je čovjeku; a siromah ne sluša opomene."},{"v":9,"t":"Svjetlost pravednička blistavo sja, a svjetiljka opakih gasi se."},{"v":10,"t":"Oholost rađa samo svađu, a mudrost je u onih koji primaju savjet."},{"v":11,"t":"Naglo stečeno bogatstvo iščezava, a tko sabire pomalo, biva bogat."},{"v":12,"t":"Predugo očekivanje ubija srce, a ispunjena želja drvo je života."},{"v":13,"t":"Tko riječ prezire, taj propada, a tko poštiva zapovijedi, plaću dobiva."},{"v":14,"t":"Pouka mudračeva izvor je životni, ona izbavlja od zamke smrti."},{"v":15,"t":"Uvid u dobro pribavlja milost, a put bezbožnika hrapav je."},{"v":16,"t":"Svatko pametan djeluje promišljeno, a bezumnik se hvališe svojom ludošću."},{"v":17,"t":"Zao glasnik zapada u zlo, a vjeran poslanik donosi spasenje."},{"v":18,"t":"Siromaštvo i sramota onomu tko odbija pouku, a tko ukor prima, doći će do časti."},{"v":19,"t":"Slatka je duši ispunjena želja, a bezumnicima je mrsko kloniti se oda zla."},{"v":20,"t":"Druži se s mudrima, i postat ćeš mudar, a tko se drži bezumnika, postaje opak."},{"v":21,"t":"Grešnika progoni zlo, a dobro je nagrada pravednima."},{"v":22,"t":"Valjan čovjek ostavlja baštinu unucima, a bogatstvo se grešnikovo čuva pravedniku."},{"v":23,"t":"Izobilje je hrane na krčevini siromaškoj, a ima i tko propada s nepravde."},{"v":24,"t":"Tko štedi šibu, mrzi na sina svog, a tko ga ljubi, na vrijeme ga opominje."},{"v":25,"t":"Pravednik ima jela do sitosti, a trbuh opakih poznaje oskudicu."}]},"14":{"hr":[{"v":1,"t":"Ženska mudrost sagradi kuću, a ludost je rukama razgrađuje."},{"v":2,"t":"Tko živi s poštenjem, boji se Jahve, a tko ide stranputicom, prezire ga."},{"v":3,"t":"U luđakovim je ustima šiba za oholost njegovu, a mudre štite vlastite usne."},{"v":4,"t":"Gdje nema volova, prazne su jasle, a obilna je žetva od snage bikove."},{"v":5,"t":"Istinit svjedok ne laže, a krivi svjedok širi laž."},{"v":6,"t":"Podsmjevač traži mudrost i ne nalazi je, a razumni lako dolazi do znanja."},{"v":7,"t":"Idi od čovjeka bezumna jer nećeš upoznati usne što zbore znanje."},{"v":8,"t":"Mudrost je pametna čovjeka u tom što pazi na svoj put, a bezumnička ludost prijevara je."},{"v":9,"t":"Luđacima je grijeh šala, a milost je Božja s poštenima."},{"v":10,"t":"Srce poznaje svoj jad, i veselje njegovo ne može dijeliti nitko drugi."},{"v":11,"t":"Dom opakih propast će, a šator će pravednika procvasti."},{"v":12,"t":"Neki se put učini čovjeku prav, a na koncu vodi k smrti."},{"v":13,"t":"I u smijehu srce osjeća bol, a poslije veselja dolazi tuga."},{"v":14,"t":"Otpadnik se siti svojim prestupcima, a dobar čovjek svojim radom."},{"v":15,"t":"Glupan vjeruje svakoj riječi, a pametan pazi na korak svoj."},{"v":16,"t":"Mudar se boji i oda zla se uklanja, a bezuman se raspaljuje i bez straha je."},{"v":17,"t":"Nagao čovjek čini ludosti, a razborit ih podnosi."},{"v":18,"t":"Glupaci baštine ludost, a mudre ovjenčava znanje."},{"v":19,"t":"Zli padaju ničice pred dobrima i opaki pred vratima pravednikovim."},{"v":20,"t":"I svom prijatelju mrzak je siromah, a bogataš ima mnogo ljubitelja."},{"v":21,"t":"Griješi tko prezire bližnjega svoga, a blago onomu tko je milostiv ubogima."},{"v":22,"t":"Koji snuju zlo, ne hode li stranputicom, a zar nisu dobrota i vjernost s onima koji snuju dobro?"},{"v":23,"t":"U svakom trudu ima probitka, a pusto brbljanje samo je na siromaštvo."},{"v":24,"t":"Mudrima je vijenac bogatstvo njihovo, a bezumnima kruna - njihova ludost."},{"v":25,"t":"Istinit svjedok izbavlja duše, a tko laži širi, taj je varalica."},{"v":26,"t":"U strahu je Gospodnjem veliko pouzdanje i njegovim je sinovima utočište."},{"v":27,"t":"Strah Gospodnji izvor je života: on izbavlja od zamke smrti."},{"v":28,"t":"Mnoštvo je naroda ponos kralju, a bez puka knez propada."},{"v":29,"t":"Tko se teško srdi, velike je razboritosti, a nabusit duhom pokazuje ludost."},{"v":30,"t":"Mirno je srce život tijelu, a ljubomor je gnjilež u kostima."},{"v":31,"t":"Tko tlači siromaha huli na stvoritelja, a časti ga tko je milostiv ubogomu."},{"v":32,"t":"Opaki propada zbog vlastite pakosti, a pravednik i u samoj smrti nalazi utočište."},{"v":33,"t":"U razumnu srcu mudrost počiva, a što je u bezumnome, to se i pokaže."},{"v":34,"t":"Pravednost uzvisuje narod, a grijeh je sramota pucima."},{"v":35,"t":"Kralju je mio razborit sluga, a na sramotna se srdi."}]},"15":{"hr":[{"v":1,"t":"Blag odgovor ublažava jarost, a riječ osorna uvećava srdžbu."},{"v":2,"t":"Jezik mudrih ljudi proslavlja znanje, a usta bezumnih prosipaju ludost."},{"v":3,"t":"Oči su Jahvine na svakome mjestu i budno motre i zle i dobre."},{"v":4,"t":"Blaga je besjeda drvo života, a pakosna je rana duhu."},{"v":5,"t":"Luđak prezire pouku oca svog, a tko ukor prima, pametno čini."},{"v":6,"t":"U pravednikovoj je kući mnogo blaga, a opaki zarađuje propast svoju."},{"v":7,"t":"Usne mudrih siju znanje, a srce je bezumnika nepostojano."},{"v":8,"t":"Žrtva opakog mrska je Jahvi, a mila mu je molitva pravednika."},{"v":9,"t":"Put opakih Jahvi je mrzak, a mio mu je onaj koji ide za pravicom."},{"v":10,"t":"Oštra kazna čeka onog tko ostavlja pravi put, a umrijet će tko mrzi ukor."},{"v":11,"t":"I Šeol i Abadon stoje pred Jahvom, a nekmoli srca sinova ljudskih."},{"v":12,"t":"Podsmjevač ne ljubi onog tko ga kori: on se ne druži s mudrima."},{"v":13,"t":"Veselo srce razvedrava lice, a bol u srcu tjeskoba je duhu."},{"v":14,"t":"Razumno srce traži znanje, a bezumnička se usta bave ludošću."},{"v":15,"t":"Svi su dani bijednikovi zli, a komu je srce sretno, na gozbi je bez prestanka."},{"v":16,"t":"Bolje je malo sa strahom Gospodnjim nego veliko blago i s njime nemir."},{"v":17,"t":"Bolji je obrok povrća gdje je ljubav nego od utovljena vola gdje je mržnja."},{"v":18,"t":"Gnjevljiv čovjek zameće svađu, a ustrpljiv utišava raspru."},{"v":19,"t":"Put je ljenivčev kao glogov trnjak, a utrta je staza pravednika."},{"v":20,"t":"Mudar sin veseli oca, a bezumnik prezire majku svoju."},{"v":21,"t":"Ludost je veselje nerazumnomu, a razuman čovjek pravo hodi."},{"v":22,"t":"Ne uspijevaju nakane kad nema vijećanja, a ostvaruju se gdje je mnogo savjetnika."},{"v":23,"t":"Čovjek se veseli odgovoru usta svojih, i riječ u pravo vrijeme - kako je ljupka!"},{"v":24,"t":"Razumnu čovjeku put života ide gore, da izmakne carstvu smrti koje je dolje."},{"v":25,"t":"Jahve ruši kuću oholima, a postavlja među udovici."},{"v":26,"t":"Mrske su Jahvi zle misli, a dobrostive riječi mile su mu."},{"v":27,"t":"Tko se grabežu oda, razara svoj dom, a tko mrzi mito, živjet će."},{"v":28,"t":"Pravednikovo srce smišlja odgovor, a opakomu usta govore zlobom."},{"v":29,"t":"Daleko je Jahve od opakih, a uslišava molitvu pravednih."},{"v":30,"t":"Bistar pogled razveseli srce i radosna vijest oživi kosti."},{"v":31,"t":"Uho koje posluša spasonosan ukor prebiva među mudracima."},{"v":32,"t":"Tko odbaci pouku, prezire vlastitu dušu, a tko posluša ukor, stječe razboritost."},{"v":33,"t":"Strah je Gospodnji škola mudrosti, jer pred slavom ide poniznost."}]},"16":{"hr":[{"v":1,"t":"Čovjek snuje u srcu, a od Jahve je što će jezik odgovoriti."},{"v":2,"t":"Čovjeku se svi njegovi putovi čine čisti, a Jahve ispituje duhove."},{"v":3,"t":"Prepusti Jahvi svoja djela, i tvoje će se namisli ostvariti."},{"v":4,"t":"Jahve je sve stvorio u svoju svrhu, pa i opakoga za dan zli."},{"v":5,"t":"Mrzak je Jahvi svatko ohola duha: takav zaista ne ostaje bez kazne."},{"v":6,"t":"Ljubavlju se i vjernošću pomiruje krivnja, i strahom se Gospodnjim uklanja zlo."},{"v":7,"t":"Kad su Jahvi mili putovi čovječji, i neprijatelje njegove miri s njim."},{"v":8,"t":"Bolje je malo s pravednošću nego veliki dohoci s nepravdom."},{"v":9,"t":"Srce čovječje smišlja svoj put, ali Jahve upravlja korake njegove."},{"v":10,"t":"Proročanstvo je na usnama kraljevim: u osudi se njegova usta neće ogriješiti."},{"v":11,"t":"Mjere i tezulje pripadaju Jahvi; njegovo su djelo i svi utezi."},{"v":12,"t":"Mrsko je kraljevima počiniti opačinu, jer se pravdom utvrđuje prijestolje."},{"v":13,"t":"Mile su kraljevima usne pravedne i oni ljube onog koji govori pravo."},{"v":14,"t":"Jarost je kraljeva vjesnik smrti ali je mudar čovjek ublaži."},{"v":15,"t":"U kraljevu je vedru licu život, i njegova je milost kao oblak s kišom proljetnom."},{"v":16,"t":"Probitačnije je steći mudrost nego zlato, i stjecati razbor dragocjenije je nego srebro."},{"v":17,"t":"Životni je put pravednih: kloniti se zla, i tko pazi na svoj put, čuva život svoj."},{"v":18,"t":"Pred slomom ide oholost i pred padom uznositost."},{"v":19,"t":"Bolje je biti krotak s poniznima nego dijeliti plijen s oholima."},{"v":20,"t":"Tko pazi na riječ, nalazi sreću, i tko se uzda u Jahvu, blago njemu."},{"v":21,"t":"Mudar srcem naziva se razumnim i prijazne usne uvećavaju znanje."},{"v":22,"t":"Izvor je životni razum onima koji ga imaju, a ludima je kazna njihova ludost."},{"v":23,"t":"Mudračev duh urazumljuje usta njegova, na usnama mu znanje umnožava."},{"v":24,"t":"Saće meda riječi su ljupke, slatke duši i lijek kostima."},{"v":25,"t":"Neki se put čini čovjeku prav, a na kraju vodi k smrti."},{"v":26,"t":"Radnikova glad radi za nj; jer ga tjeraju usta njegova."},{"v":27,"t":"Bezočnik pripravlja samo zlo i na usnama mu je oganj plameni."},{"v":28,"t":"Himben čovjek zameće svađu i klevetnik razdor među prijatelje."},{"v":29,"t":"Nasilnik zavodi bližnjega svoga i navodi ga na rđav put."},{"v":30,"t":"Tko očima namiguje, himbu smišlja, a tko usne stišće, već je smislio pakost."},{"v":31,"t":"Sijede su kose prekrasna kruna, nalaze se na putu pravednosti."},{"v":32,"t":"Tko se teško srdi, bolji je od junaka, i tko nad sobom vlada, bolji je od osvojitelja grada."},{"v":33,"t":"U krilo plašta baca se kocka, ali je od Jahve svaka odluka."}]},"17":{"hr":[{"v":1,"t":"Bolji je zalogaj suha kruha s mirom nego sa svađom kuća puna žrtvene pečenke."},{"v":2,"t":"Razuman sluga vlada nad sinom sramotnim i s braćom će dijeliti baštinu."},{"v":3,"t":"Taljika je za srebro i peć za zlato, a srca iskušava Jahve sam."},{"v":4,"t":"Zločinac rado sluša usne prijevarne, i lažac spremno prisluškuje pogubnu jeziku."},{"v":5,"t":"Tko se ruga siromahu, podruguje se Stvoritelju njegovu, i tko se veseli nesreći, ne ostaje bez kazne."},{"v":6,"t":"Unuci su vijenac starcima, a sinovima ures oci njihovi."},{"v":7,"t":"Ne dolikuje budali uzvišena besjeda, a još manje odličniku usne lažljive."},{"v":8,"t":"Dar je čarobni kamen u očima onoga koji ga daje: kamo se god okrene, uspijeva."},{"v":9,"t":"Tko prikriva prijestup, traži ljubav, a tko glasinu širi, razgoni prijatelje."},{"v":10,"t":"Razumna se ukor jače doima nego bezumna stotina udaraca."},{"v":11,"t":"Opak čovjek ide samo za zlom, ali se okrutan glasnik šalje na nj."},{"v":12,"t":"Bolje je nabasati na medvjedicu kojoj ugrabiše mlade nego na bezumnika u njegovoj ludosti."},{"v":13,"t":"Tko dobro zlom uzvraća neće ukloniti nesreću od doma svojeg."},{"v":14,"t":"Zametnuti svađu isto je kao pustiti poplavu: stoga prije nego svađa izbije, udalji se!"},{"v":15,"t":"Tko opravdava krivoga i tko osuđuje pravoga, obojica su mrski Jahvi."},{"v":16,"t":"Čemu novac u ruci bezumnomu? Da njime mudrost kupi, kad nema razbora!"},{"v":17,"t":"Prijatelj ljubi u svako vrijeme, a u nevolji i bratom postaje."},{"v":18,"t":"Nerazuman čovjek daje ruku i jamči pred svojim bližnjim."},{"v":19,"t":"Grijeh ljubi tko ljubi svađu, i tko visoko diže svoja vrata, traži propast."},{"v":20,"t":"Opak srcem ne nalazi sreće, i komu je jezik zao, zapada u nesreću."},{"v":21,"t":"Tko rodi bezumna, na tugu mu je; a nije veseo ni otac budale."},{"v":22,"t":"Veselo je srce izvrstan lijek, a neveseo duh suši kosti."},{"v":23,"t":"Opaki prima dar iz njedara da bi iskrivio putove pravici."},{"v":24,"t":"Razuman ima mudrost pred sobom, a bezumniku su oči na kraj zemlje."},{"v":25,"t":"Briga je ocu bezuman sin i žalost roditeljki svojoj."},{"v":26,"t":"Ne valja kažnjavati pravednika, a nije pravo ni tući odličnike."},{"v":27,"t":"Tko usteže svoje riječi, razumije mudrost, i razuman je čovjek mirna duha."},{"v":28,"t":"I luđak se smatra mudrim kada šuti i razumnim kad susteže svoje usne."}]},"18":{"hr":[{"v":1,"t":"Vlastitoj požudi popušta onaj tko zastranjuje, i svađa se usprkos svakom razboru."},{"v":2,"t":"Bezumnomu nije mio razum; stalo mu je dati srcu oduška."},{"v":3,"t":"Kad dolazi opačina, dolazi i prezir i bruka sa sramotom."},{"v":4,"t":"Duboke su vode riječi iz usta nečijih, izvor mudrosti bujica što se razlijeva."},{"v":5,"t":"Ne valja se obazirati na opaku osobu, da se pravedniku nanese nepravda na sudu."},{"v":6,"t":"Bezumnikove se usne upuštaju u svađu i njegova usta izazivlju udarce."},{"v":7,"t":"Bezumnomu su propast vlastita usta i usne su mu zamka životu."},{"v":8,"t":"Klevetnikove su riječi kao poslastice: spuštaju se u dno utrobe."},{"v":9,"t":"Tko je nemaran u svom poslu, brat je onomu koji rasipa."},{"v":10,"t":"Tvrda je kula ime Jahvino: njemu se pravednik utječe i nalazi utočišta."},{"v":11,"t":"Bogatstvo je bogatašu njegova tvrđava i kao visok zid u mašti njegovoj."},{"v":12,"t":"Pred slomom se oholi srce čovječje, a pred slavom ide poniznost."},{"v":13,"t":"Tko odgovara prije nego što sasluša, na ludost mu je i sramotu."},{"v":14,"t":"Kad je čovjek bolestan, njegov ga duh podiže, a ubijen duh tko će podići?"},{"v":15,"t":"Razumno srce stječe znanje i uho mudrih traži znanje."},{"v":16,"t":"Dar čovjeku otvara put i vodi ga pred velikaše."},{"v":17,"t":"Prvi je pravedan u svojoj parnici, a kad dođe njegov protivnik, opovrgne ga."},{"v":18,"t":"Ždrijeb poravna svađe, pa i među moćnicima odlučuje."},{"v":19,"t":"Uvrijeđen brat jači je od tvrda grada i svađe su kao prijevornice na tvrđavi."},{"v":20,"t":"Svatko siti trbuh plodom usta svojih, nasićuje se rodom usana svojih."},{"v":21,"t":"Smrt i život u vlasti su jeziku, a tko ga miluje, jede od ploda njegova."},{"v":22,"t":"Tko je našao ženu, našao je sreću i stekao milost od Jahve."},{"v":23,"t":"Ponizno moleći govori siromah, a grubo odgovara bogataš."},{"v":24,"t":"Ima prijatelja koji vode u propast, a ima i prijatelja privrženijih od brata."}]},"19":{"hr":[{"v":1,"t":"Bolji je siromah koji živi u nedužnosti nego čovjek opakih usana i k tomu bezuman."},{"v":2,"t":"Revnost bez razboritosti nije dobra, i tko brzo hoda, spotiče se."},{"v":3,"t":"Ludost čovjeku kvari život, a srce mu se ljuti na Jahvu!"},{"v":4,"t":"Bogatstvo pribavlja mnoge prijatelje, a siromaha i njegov prijatelj ostavlja."},{"v":5,"t":"Lažljiv svjekok ne ostaje bez kazne, i tko širi laži, neće uteći."},{"v":6,"t":"Mnogi laskaju licu odličnikovu i svatko je prijatelj čovjeku darežljivu."},{"v":7,"t":"Na siromaha mrze sva braća njegova, još više se udaljuju od njega prijatelji njegovi: on hlepi za dobrim riječima, ali ih ne nalazi!"},{"v":8,"t":"Tko stječe razboritost, ljubi sebe, a tko čuva razum, nalazi sreću."},{"v":9,"t":"Lažljiv svjedok ne ostaje bez kazne, i tko širi laži, propada."},{"v":10,"t":"Ne dolikuje bezumnomu živjeti raskošno, a još manje sluzi vlast nad knezovima."},{"v":11,"t":"Um čovjeka usteže od srdžbe, a čast mu je oprostiti krivicu."},{"v":12,"t":"Kraljev je gnjev kao rika lavlja, a njegova milost kao rosa bilju."},{"v":13,"t":"Nesreća je ocu svojemu bezuman sin, i neprestano prokišnjavanje svađe su ženine."},{"v":14,"t":"Kuća se i bogatstvo baštine od otaca, a od Jahve je žena razumna."},{"v":15,"t":"Lijenost navlači čovjeku dubok san i nemarna duša gladuje."},{"v":16,"t":"Tko se drži zapovijedi, čuva život svoj, a tko ne pazi putove svoje, umire."},{"v":17,"t":"Jahvi pozaima tko je siromahu milostiv, i on će mu platiti dobročinstvo."},{"v":18,"t":"Kažnjavaj sina svoga dok ima nade, ali ne idi za tim da ga ubiješ."},{"v":19,"t":"Tko je jarostan, plaća globu, i kad ga štediš, samo uvećavaš njegov gnjev."},{"v":20,"t":"Slušaj savjet i primaj pouku, kako bi naposljetku postao mudar."},{"v":21,"t":"Mnogo je namisli u srcu čovječjem, ali što Jahve naumi, to i bude."},{"v":22,"t":"Dražest je čovjekova u dobroti njegovoj, i bolji je siromah od lažljivca."},{"v":23,"t":"Strah Gospodnji daje život, i tko se njime ispuni, zlo ga ne pohodi."},{"v":24,"t":"Lijenčina umače ruku u zdjelu, ali je ustima svojim ne prinosi."},{"v":25,"t":"Udari podsmjehivača, i lud se opameti; ukori razumnog, i shvatit će znanje."},{"v":26,"t":"Sin je sramotan i pokvaren tko zlostavlja oca i odgoni majku."},{"v":27,"t":"Prestani, sine moj, slušati naputke koji odvode od riječi spoznaje!"},{"v":28,"t":"Nevaljao se svjedok podruguje pravdi i usta opakih gutaju nepravdu."},{"v":29,"t":"Pripravljene su kazne podsmjevačima i udarci za leđa bezumnika."}]},"20":{"hr":[{"v":1,"t":"Vino je podsmjevač, žestoko piće bukač, i tko se njima odaje neće steći mudrosti."},{"v":2,"t":"Kraljev je gnjev kao rika lavlja: tko ga izaziva, griješi protiv sebe samog."},{"v":3,"t":"Čast je čovjeku ustegnuti se od raspre, a tko je bezuman počinje svađu."},{"v":4,"t":"Lijenčina u jesen ne ore: u doba žetve on traži, i ništa nema."},{"v":5,"t":"Savjet je u srcu čovječjem voda duboka i razuman će je čovjek iscrpsti."},{"v":6,"t":"Mnogi se naziva dobrim čovjekom, ali tko će naći vjerna čovjeka?"},{"v":7,"t":"Pravednik hodi u bezazlenosti svojoj: blago sinovima njegovim poslije njega!"},{"v":8,"t":"Kralj koji sjedi na stolici sudačkoj istražuje svako zlo svojim očima."},{"v":9,"t":"Tko može reći: “Očistih srce svoje, oprah se od grijeha svoga?”"},{"v":10,"t":"Dvojaki utezi i dvojaka mjera mrski su Jahvi podjednako."},{"v":11,"t":"I dijete se poznaje po onome što čini, je li čisto i pravedno djelo njegovo."},{"v":12,"t":"I uho koje čuje i oko koje vidi, oboje je Jahve načinio."},{"v":13,"t":"Ne ljubi sna, da ne osiromašiš; otvori oči svoje i nasitit ćeš se kruha."},{"v":14,"t":"“Loše, loše”, govori kupac, a kad ode, hvali se dobrom kupovinom."},{"v":15,"t":"Ima zlata i mnogih bisera, ali su mudre usne najdragocjeniji nakit."},{"v":16,"t":"Uzmi haljinu onomu tko je jamčio za drugoga; oplijeni njega umjesto tuđinca."},{"v":17,"t":"Sladak je čovjeku kruh prijevare, ali mu se usta poslije napune pijeskom."},{"v":18,"t":"Naumi se provode savjetom: zato dobro razmisli pa vodi boj!"},{"v":19,"t":"Tko okolo kleveće, otkriva tajne: zato se ne miješaj s onim komu su usne uvijek otvorene."},{"v":20,"t":"Tko kune oca svoga i majku svoju svjetiljka mu se gasi usred tmine."},{"v":21,"t":"Od početka brzo stečeno imanje na koncu nije blagoslovljeno."},{"v":22,"t":"Nemoj govoriti: “Osvetit ću se za zlo”; čekaj Jahvu, i on će te spasiti."},{"v":23,"t":"Mrski su Jahvi dvojaki utezi, i kriva mjera ne valja."},{"v":24,"t":"Od Jahve su koraci čovječji, i kako da čovjek razumije svoj put?"},{"v":25,"t":"Zamka je čovjeku nesmotreno reći: “Ovo je sveto”, a poslije promišljati što je zavjetovao."},{"v":26,"t":"Mudar kralj umije izlučiti opake i stavlja ih pod točkove."},{"v":27,"t":"Svjetiljka je Gospodnja duh čovječji: ona istražuje sve do dna utrobe."},{"v":28,"t":"Dobrota i vjernost čuvaju kralja, jer dobrotom utvrđuje prijestol svoj."},{"v":29,"t":"Ljepota je mladićima njihova snaga, a starcima je ures sijeda kosa."},{"v":30,"t":"Krvave masnice očiste zlo i udarci pročiste odaje utrobe."}]},"21":{"hr":[{"v":1,"t":"Kraljevo je srce u ruci Jahve kao voda tekućica; vodi ga kuda god hoće."},{"v":2,"t":"Svaki je put čovjeku pravedan u vlastitim očima, a Jahve ispituje srca."},{"v":3,"t":"Da se vrši pravda i čini pravo, draže je Jahvi nego žrtva."},{"v":4,"t":"Ponosite oči i oholo srce i svjetiljka opakih - to je grijeh."},{"v":5,"t":"Namisli marljivoga samo su na korist, a nagloga samo na siromaštvo."},{"v":6,"t":"Blago stečeno jezikom lažljivim nestalna je ispraznost onih koji traže smrt."},{"v":7,"t":"Opake će odnijeti nasilje njihovo jer ne žele činiti pravice."},{"v":8,"t":"Zapleten je put zločinca, a pravo je djelo čista čovjeka."},{"v":9,"t":"Bolje je živjeti pod rubom krova nego u zajedničkoj kući sa ženom svadljivom."},{"v":10,"t":"Duša opakoga želi zlo: u njega nema samilosti ni za bližnjega."},{"v":11,"t":"Kad se podsmjevač kazni, neiskusan postaje mudar, a mudri iz pouke crpe znanje."},{"v":12,"t":"Na kuću opakoga pazi Svepravedni i opake strovaljuje u nesreću."},{"v":13,"t":"Tko zatvori uho svoje pred vikom siromaha, i sam će vikati, ali ga neće nitko uslišati."},{"v":14,"t":"Potajan dar utišava srdžbu, a poklon ispod ruke i žestoku jarost."},{"v":15,"t":"Sud pravičan radost je pravedniku a užas zločincima."},{"v":16,"t":"Čovjek koji skreće s puta razbora počivat će u zboru mrtvačkom."},{"v":17,"t":"Tko ljubi veselje, postaje siromah, i tko ljubi vino i mirisno ulje, ne obogati se."},{"v":18,"t":"Opak čovjek otkup je za pravednika, i bezbožnik stupa na mjesto pravednog."},{"v":19,"t":"Bolje je živjeti u pustinji nego sa ženom svadljivom i gnjevljivom."},{"v":20,"t":"Krasno je blago i ulje u stanu mudroga, a bezuman ih čovjek rasipa."},{"v":21,"t":"Tko teži za pravdom i dobrohotnošću, nalazi život i čast."},{"v":22,"t":"Mudrac nadvladava i grad pun ratnika i krši silu u koju su se uzdali."},{"v":23,"t":"Tko čuva usta i jezik svoj, čuva sebe od nevolje."},{"v":24,"t":"Drzovitom i oholici ime je “podsmjevač”; on sve radi s prekomjernom drskošću."},{"v":25,"t":"Lijenčinu ubija želja njegova jer mu ruke bježe od posla."},{"v":26,"t":"Opak po cio dan živo želi, a pravednik daje i ne škrtari."},{"v":27,"t":"Mrska je žrtva opakih, osobito kad se požudno prinosi."},{"v":28,"t":"Lažljiv svjedok propada, a čovjek koji sluša, opet će govoriti."},{"v":29,"t":"Opaki pokazuju drsko lice, a poštenjak učvršćuje put svoj."},{"v":30,"t":"Nema mudrosti i nema razuma i nema savjeta protiv Jahve."},{"v":31,"t":"Konj se oprema za dan boja, ali Jahve daje pobjedu."}]},"22":{"hr":[{"v":1,"t":"Dobro je ime bolje od velika bogatstva, i bolja je naklonost od srebra i zlata."},{"v":2,"t":"Bogataš se i siromah sreću: obojicu ih Jahve stvori."},{"v":3,"t":"Pametan čovjek vidi zlo i skrije se, a glupaci idu bezbrižno i trpe kaznu."},{"v":4,"t":"Nagrada je poniznosti strah Gospodnji, bogatstvo, čast i život."},{"v":5,"t":"Trnje i zamke su na putu varalici: tko čuva život svoj, daleko je od oboga."},{"v":6,"t":"Upućuj dijete prema njegovu putu, pa kad i ostari, neće odstupiti od njega."},{"v":7,"t":"Bogataš vlada nad siromasima, a dužnik je sluga vjerovniku."},{"v":8,"t":"Tko sije nepravdu, žanje nesreću, i šiba njegova gnjeva udarit će njega samog."},{"v":9,"t":"Milostivo se oko blagoslivlje, jer daje od svog kruha siromahu."},{"v":10,"t":"Otjeraj podsmjevača i prestat će svađe i nestat će nesloga i pogrda."},{"v":11,"t":"Jahve ljubi čisto srce, i tko je ljubeznih usana, kralj mu je prijatelj."},{"v":12,"t":"Pogled Jahvin čuva znanje, Jahve pomućuje riječi bezbožnika."},{"v":13,"t":"Lijenčina veli: “Lav je vani, nasred trga poginuo bih.”"},{"v":14,"t":"Duboka jama usta su preljubnice, i na koga se Jahve srdi, pada onamo."},{"v":15,"t":"Ludost prianja uza srce djetinje: šiba pouke otklanja je od njega."},{"v":16,"t":"Tko tlači siromaha, taj mu koristi; tko daje bogatašu, samo mu šteti."},{"v":17,"t":"Riječi mudraca: Prigni uho svoje i čuj riječi moje i upravi svoje srce mojem znanju,"},{"v":18,"t":"jer milina je ako ih čuvaš u nutrini svojoj, i kad ti budu sve spremne na usnama tvojim."},{"v":19,"t":"Da bi uzdanje tvoje bilo u Jahvi, upućujem danas i tebe."},{"v":20,"t":"Napisah ti trideset što savjeta što pouka"},{"v":21,"t":"da te poučim riječima istine, da uzmogneš pouzdanim riječima odgovoriti onomu tko te zapita."},{"v":22,"t":"Nemoj pljačkati siromaha zato što je siromah i ne gazi ubogoga na sudu."},{"v":23,"t":"Jer će Jahve parbiti parbu njihovu i otet će život onima koji ga njima otimlju."},{"v":24,"t":"Ne druži se sa srditim i ne idi s čovjekom jedljivim"},{"v":25,"t":"da se ne bi privikao na staze njegove i namjestio zamku duši svojoj."},{"v":26,"t":"Ne budi među onima koji daju ruku, koji jamče za dugove:"},{"v":27,"t":"ako nemaš čime nadoknaditi, zašto da ti oduzmu i postelju ispod tebe?"},{"v":28,"t":"Ne pomiči prastare međe koju su postavili oci tvoji."},{"v":29,"t":"Jesi li vidio čovjeka vična poslu svom: takav ima pristup kraljevima i ne služi prostacima."}]},"23":{"hr":[{"v":1,"t":"Kad sjedneš blagovati s moćnikom. dobro pazi što je pred tobom;"},{"v":2,"t":"stavljaš nož sebi pod grlo ako si proždrljivac;"},{"v":3,"t":"ne poželi slastica njegovih jer su jelo prijevarno."},{"v":4,"t":"Ne trudi se stjecati bogatstvo; okani se takve misli;"},{"v":5,"t":"usmjeriš li oči prema njemu, njega već nema jer načini sebi krila kao orao i odleti u nebo."},{"v":6,"t":"Ne jedi jela zavidnikova, ne čezni za slasticama njegovim,"},{"v":7,"t":"jer on je onakav kako u sebi misli: “Jedi i pij”, veli ti, ali mu srce nije s tobom."},{"v":8,"t":"Zalogaj koji si pojeo izbljuvat ćeš, uzalud ćeš prosut' svoje ljupke riječi."},{"v":9,"t":"Pred bezumnikom nemoj govoriti jer prezire tvoje umne riječi."},{"v":10,"t":"Ne pomiči prastare međe i ne prodiri u polje siročadi,"},{"v":11,"t":"jer je moćan njihov osvetnik: branit će njihovo pravo protiv tebe."},{"v":12,"t":"Obrati pouci srce svoje i uho svoje riječima mudrim."},{"v":13,"t":"Ne uskraćuj djetetu opomene, jer, udariš li ga šibom, neće umrijeti:"},{"v":14,"t":"biješ ga šibom, ali mu dušu iz Podzemlja izbavljaš."},{"v":15,"t":"Sine moj, kad ti je mudro srce, i ja se od srca veselim;"},{"v":16,"t":"i kliče sva nutrina moja kad ti usne govore što je pravo."},{"v":17,"t":"Neka ti srce ne zavidi grešnicima, nego neka ti uvijek bude u strahu Gospodnjem,"},{"v":18,"t":"jer imat ćeš budućnost i tvoja nada neće propasti."},{"v":19,"t":"Slušaj, sine moj, i mudar budi i ravnim putem vodi srce svoje."},{"v":20,"t":"Ne druži se s vinopijama ni sa žderačima mesa,"},{"v":21,"t":"jer pijanica i izjelica osiromaše i pospanac se oblači u krpe."},{"v":22,"t":"Slušaj svoga oca, svoga roditelja, i ne prezri majku kad ostari."},{"v":23,"t":"Pribavi istinu i ne prodaji je, steci mudrost, pouku i razbor."},{"v":24,"t":"Radovat će se otac pravednikov, i roditelj će se mudroga veseliti."},{"v":25,"t":"Neka se veseli otac tvoj i majka tvoja, i neka se raduje roditeljka tvoja."},{"v":26,"t":"Daj mi, sine moj, srce svoje, i neka oči tvoje raduju putovi moji."},{"v":27,"t":"Jer bludnica je jama duboka i tuđinka tijesan zdenac."},{"v":28,"t":"Ona i vreba u zasjedi kao lupež i uvećava broj bezbožnika među ljudima."},{"v":29,"t":"Komu: ah? komu: jao? komu: svađe? komu: uzdasi? komu: rane nizašto? komu: zamućene oči?"},{"v":30,"t":"Onima što kasno sjede kod vina, koji su došli kušati vino začinjeno."},{"v":31,"t":"Ne gledaj na vino kad rujno iskri, kad se u čaši svjetlucavo prelijeva: pije se tako glatko,"},{"v":32,"t":"a na kraju ujeda kao zmija i žaca kao guja ljutica."},{"v":33,"t":"Oči će ti gledati tlapnje i srce govoriti ludosti."},{"v":34,"t":"I bit će ti kao da ležiš na pučini morskoj ili kao da ležiš navrh jarbola."},{"v":35,"t":"“Izbiše me, ali me ne zabolje; istukoše me, ali ne osjetih; kad se otrijeznim, još ću tražiti.”"}]},"24":{"hr":[{"v":1,"t":"Ne zavidi opakim ljudima niti želi da budeš s njima."},{"v":2,"t":"Jer im srce smišlja nasilje i usne govore o nedjelu."},{"v":3,"t":"Mudrošću se zida kuća i razborom utvrđuje,"},{"v":4,"t":"i po znanju se pune klijeti svakim blagom dragocjenim i ljupkim."},{"v":5,"t":"Bolji je mudar od jakoga i čovjek razuman od silne ljudine."},{"v":6,"t":"Jer s promišljanjem se ide u boj i pobjeda je u mnoštvu savjetnika."},{"v":7,"t":"Previsoka je bezumnomu mudrost: zato na sudu ne otvara usta svojih!"},{"v":8,"t":"Tko smišlja zlo zove se učitelj podmukli."},{"v":9,"t":"Ludost samo grijeh snuje, i podrugljivac je mrzak ljudima."},{"v":10,"t":"Kloneš li u dan bijede, bijedna je tvoja snaga."},{"v":11,"t":"Izbavi one koje vode u smrt; i spasavaj one koji posrćući idu na stratište."},{"v":12,"t":"Ako kažeš: “Nismo za to znali”, ne razumije li onaj koji ispituje srca? I ne znade li onaj koji ti čuva dušu? I ne plaća li on svakomu po njegovim djelima?"},{"v":13,"t":"Jedi med, sine moj, jer je dobar, i saće je slatko nepcu tvome."},{"v":14,"t":"Takva je, znaj, i mudrost tvojoj duši: ako je nađeš, našao si budućnost i nada tvoja neće propasti."},{"v":15,"t":"Ne postavljaj, opaki, zasjede stanu pravednikovu, ne čini nasilja boravištu njegovu;"},{"v":16,"t":"jer padne li pravednik i sedam puta, on ustaje, a opaki propadaju u nesreći."},{"v":17,"t":"Ne veseli se kad padne neprijatelj tvoj i ne kliči srcem kada on posrće,"},{"v":18,"t":"da ne bi vidio Jahve i za zlo uzeo i obratio srdžbu svoju od njega."},{"v":19,"t":"Nemoj se srditi zbog zločinaca, nemoj zavidjeti opakima,"},{"v":20,"t":"jer zao čovjek nema budućnosti, svjetiljka opakih gasi se."},{"v":21,"t":"Boj se Jahve, sine moj, i kralja: i ne buni se ni protiv jednoga ni protiv drugoga."},{"v":22,"t":"Jer iznenada provaljuje nesreća njihova i tko zna kad će doći propast njihova."},{"v":23,"t":"I ovo je od mudraca: Ne valja biti pristran na sudu."},{"v":24,"t":"Tko opakomu veli: “Pravedan si”, proklinju ga narodi i kunu puci;"},{"v":25,"t":"a oni koji ga ukore nalaze zadovoljstvo, i na njih dolazi blagoslov sreće."},{"v":26,"t":"U usta ljubi tko odgovara pošteno."},{"v":27,"t":"Svrši svoj posao vani i uredi svoje polje, potom i kuću svoju zidaj."},{"v":28,"t":"Ne svjedoči lažno na bližnjega svoga: zar ćeš varati usnama svojim?"},{"v":29,"t":"Ne reci: “Kako je on meni učinio, tako ću i ja njemu; platit ću tom čovjeku po djelu njegovu!”"},{"v":30,"t":"Prolazio sam mimo polje nekog lijenčine i mimo vinograd nekog luđaka,"},{"v":31,"t":"i gle, sve bijaše zaraslo u koprive, i sve pokrio čkalj, i kamena ograda porušena."},{"v":32,"t":"Vidjeh to i pohranih u srcu, promotrih i uzeh pouku:"},{"v":33,"t":"“Još malo odspavaj, još malo odrijemaj, još malo podvij ruke za počinak,"},{"v":34,"t":"i doći će tvoje siromaštvo kao skitač i oskudica kao oružanik!”"}]},"25":{"hr":[{"v":1,"t":"I ovo su mudre izreke Salomonove; sabrali ih ljudi Ezekije, kralja judejskog."},{"v":2,"t":"Slava je Božja sakrivati stvar, a slava kraljevska istraživati je."},{"v":3,"t":"Neistražljivo je nebo u visinu, zemlja u dubinu i srce kraljevsko."},{"v":4,"t":"Ukloni trosku od srebra, i uspjet će posao zlataru."},{"v":5,"t":"Ukloni opakoga ispred kralja, i utvrdit će se pravicom prijestol njegov."},{"v":6,"t":"Ne veličaj se pred kraljem i ne sjedaj na mjesto velikaško,"},{"v":7,"t":"jer je bolje da ti se kaže: “Popni se gore” nego da te ponize pred odličnikom."},{"v":8,"t":"Što su ti oči vidjele ne iznosi prebrzo na raspru; jer što ćeš učiniti na koncu kad te opovrgne bližnji tvoj?"},{"v":9,"t":"Kad si u parbi s bližnjim svojim, ne otkrivaj tuđe tajne,"},{"v":10,"t":"da te ne izgrdi tko čuje i da ti se kleveta ne vrati."},{"v":11,"t":"Riječi kazane u pravo vrijeme zlatne su jabuke u srebrnim posudama."},{"v":12,"t":"Mudrac koji kori uhu je poslušnu zlatan prsten i ogrlica od tanka zlata."},{"v":13,"t":"Vjeran je glasnik onomu tko ga šalje kao ledena studen u doba žetve: on krijepi dušu svoga gospodara."},{"v":14,"t":"Tko se diči lažljivim darom, on je kao oblak i vjetar bez kiše."},{"v":15,"t":"Strpljivošću se ublažava sudac, mek jezik i kosti lomi."},{"v":16,"t":"Kad naiđeš na med, jedi umjereno, kako se ne bi prejeo i pojedeno izbljuvao."},{"v":17,"t":"Rijetko zalazi u kuću bližnjega svoga, da te se ne zasiti i ne zamrzi na te."},{"v":18,"t":"Čovjek koji svjedoči lažno na bližnjega svoga on je kao bojni malj i mač i oštra strijela."},{"v":19,"t":"Uzdanje u bezbožnika na dan nevolje - krnjav je zub i noga klecava."},{"v":20,"t":"Kao onaj koji skida haljinu u zimski dan ili ocat lije na ranu, takav je onaj tko pjeva pjesmu turobnu srcu."},{"v":21,"t":"Ako je gladan neprijatelj tvoj, nahrani ga kruhom, i ako je žedan, napoji ga vodom."},{"v":22,"t":"Jer mu zgrćeš ugljevlje na glavu i Jahve će ti platiti."},{"v":23,"t":"Sjeverni vjetar donosi dažd, a himben jezik srdito lice."},{"v":24,"t":"Bolje je stanovati pod rubom krova nego u zajedničkoj kući sa ženom svadljivom."},{"v":25,"t":"Kao studena voda žednu grlu, takva je dobra vijest iz zemlje daleke."},{"v":26,"t":"Kao zatrpan izvor i vrelo zamućeno, takav je pravednik koji kleca pred opakim."},{"v":27,"t":"Jesti mnogo meda nije dobro niti tražiti pretjerane časti."},{"v":28,"t":"Grad razvaljen i bez zidova - takav je čovjek koji nema vlasti nad sobom."}]},"26":{"hr":[{"v":1,"t":"Kao snijeg ljeti ili kiša o žetvi, tako pristaju počasti bezumnomu."},{"v":2,"t":"Kao vrabac kad prhne i lastavica kad odleti, tako se i bezrazložna kletva ne ispunja."},{"v":3,"t":"Bič konju, uzda magarcu, a šiba leđima bezumnika."},{"v":4,"t":"Ne odgovaraj bezumniku po njegovoj ludosti, da mu i sam ne postaneš jednak."},{"v":5,"t":"Odgovori bezumniku po ludosti njegovoj, da se ne bi učinio sam sebi mudar."},{"v":6,"t":"Odsijeca noge sebi i gorčinu pije tko po bezumnom poruke šalje."},{"v":7,"t":"Klecava bedra u hromoga - mudra je izreka u ustima bezumničkim."},{"v":8,"t":"Kamen za praćku vezuje tko bezumnom iskazuje čast."},{"v":9,"t":"Trnovita grana u ruci pijanice: mudra izreka u ustima bezumnika."},{"v":10,"t":"Strijelac koji ranjava sve prolaznike: takav je onaj tko unajmljuje bezumnika."},{"v":11,"t":"Bezumnik se vraća svojoj ludosti kao što se pas vraća na svoju bljuvotinu."},{"v":12,"t":"Vidiš li čovjeka koji se sam sebi mudrim čini? Znaj, i od bezumnika ima više nade nego od njega!"},{"v":13,"t":"Lijenčina veli: “Zvijer je na putu, i lav je na ulicama.”"},{"v":14,"t":"Kao što se vrata okreću na stožerima svojim, tako i lijenčina na postelji svojoj."},{"v":15,"t":"Lijenčina umače ruku u zdjelu, ali je ne može prinijeti ustima."},{"v":16,"t":"Lijenčina se čini sebi mudrijim od sedmorice koji umno odgovaraju."},{"v":17,"t":"Psa za uši hvata tko se, u prolazu, umiješa u raspru koja ga se ne tiče."},{"v":18,"t":"Kao bjesomučnik koji baca zublje, strelice i sije smrt,"},{"v":19,"t":"takav je čovjek koji vara bližnjega svoga i veli: “Samo se našalih.”"},{"v":20,"t":"Kad nestane drva, oganj se gasi, i kad više nema klevetnika, prestaje svađa."},{"v":21,"t":"Ugljen je za žeravnicu i drvo za oganj, a svadljivac da raspaljuje svađu."},{"v":22,"t":"Klevetnikove su riječi kao slastice: spuštaju se u dno utrobe."},{"v":23,"t":"Srebrna gleđa preko zemljana suđa: laskave usne i opako srce."},{"v":24,"t":"Mrzitelj hini usnama svojim, a u sebi nosi prijevaru;"},{"v":25,"t":"ne vjeruj mu kad ljupkim glasom govori, jer u srcu mu je sedam grdila;"},{"v":26,"t":"ako himbom skriva mržnju, njegova će se opačina otkriti na zboru."},{"v":27,"t":"Tko jamu kopa, sam u nju pada, i tko kamen valja, na njega se prevaljuje."},{"v":28,"t":"Lažljiv jezik mrzi svoje žrtve, laskava usta propast spremaju."}]},"27":{"hr":[{"v":1,"t":"Ne hvali se danom sutrašnjim jer ne znaš što danas može donijeti."},{"v":2,"t":"Neka te hvali drugi, a ne tvoja usta, tuđinac, a ne tvoje usne."},{"v":3,"t":"Težak je kamen i pijesak je težak, ali je od obojega teži bezumnikov bijes."},{"v":4,"t":"Jarost je okrutna i srdžba žestoka a tko će odoljeti ljubomoru?"},{"v":5,"t":"Bolji je javni ukor nego lažna ljubav."},{"v":6,"t":"Čestiti su udarci prijateljevi, a lažni poljupci neprijateljevi."},{"v":7,"t":"Sito grlo prezire i med samotok, a gladnu je i sve gorko - slatko."},{"v":8,"t":"Kao ptica daleko od gnijezda svog, takav je čovjek daleko od svojeg zavičaja."},{"v":9,"t":"Kao što ulje i kad vesele srce, tako i slatkoća prijateljstva tješi dušu."},{"v":10,"t":"Ne ostavljaj prijatelja svoga ni prijatelja očeva i ne dolazi u kuću bratovu kad si u nesreći; bolji je susjed blizu nego brat daleko."},{"v":11,"t":"Budi mudar, sine moj, i obraduj mi srce da mogu odgovoriti onome koji me grdi."},{"v":12,"t":"Pametan čovjek opazi zlo i skrije se, a glupaci idu bezbrižno i trpe kaznu."},{"v":13,"t":"Uzmi haljinu onomu tko je jamčio za drugoga i oplijeni ga mjesto tuđinca."},{"v":14,"t":"Tko pozdravlja svoga prijatelja naglas, a rano ujutro, prima mu se blagoslov za kletvu."},{"v":15,"t":"Streha što prokišnjava za žestoke kiše i svadljiva žena - jedno su te isto."},{"v":16,"t":"Tko nju zaustavlja, zaustavlja vjetar i desnicom hvata ulje."},{"v":17,"t":"Željezo se željezom oštri i čovjek oštri jedan drugoga."},{"v":18,"t":"Tko čuva smokvu, jede od njena ploda, i tko čuva svoga gospodara, poštiva se."},{"v":19,"t":"Kao što se u vodi različito odražava lice od lica, tako i u srcu čovjek od čovjeka."},{"v":20,"t":"Carstvo Smrti i Propast ne mogu se zasititi, tako ni oči čovječje."},{"v":21,"t":"Taljika je za srebro i peć za zlato, a čovjek se poznaje po ustima koja ga hvale."},{"v":22,"t":"Da bezumnika stučeš tučkom u stupi, ne bi ga ostavila ludost njegova."},{"v":23,"t":"Brižno pazi na stoku svoju i srcem se brini o stadima,"},{"v":24,"t":"jer blago ne traje dovijeka; i baštini li se kruna od koljena do koljena?"},{"v":25,"t":"Kad trava nikne i zelen se pokaže i bilje se kupi planinsko,"},{"v":26,"t":"tad su ti janjci za odijelo i jarci za kupovinu polja;"},{"v":27,"t":"tad imaš izobilje kozjega mlijeka sebi za jelo, i za hranu kući svojoj i za prehranu sluškinjama svojim."}]},"28":{"hr":[{"v":1,"t":"Opaki bježe i kad ih nitko ne progoni, a pravednici su neustrašivi kao mladi lav."},{"v":2,"t":"Kad se u zemlji griješi, mnogi su joj knezovi, a s čovjekom razumnim i umnim uprava je postojana."},{"v":3,"t":"Čovjek opak koji tlači ubogoga - kiša je razorna poslije koje kruha nema."},{"v":4,"t":"Koji zapuštaju Zakon, veličaju opake, a koji se drže Zakona, protive im se."},{"v":5,"t":"Zli ljudi ne razumiju pravice, a koji traže Jahvu, razumiju sve."},{"v":6,"t":"Bolji je siromah koji živi bezazleno nego bogataš koji kroči krivim putem."},{"v":7,"t":"Tko se drži Zakona, razuman je sin, a tko se druži s izbjeglicama, sramoti oca svoga."},{"v":8,"t":"Tko umnožava bogatstvo svoje lihvom i pridom, skuplja ga onomu tko je milostiv ubogima."},{"v":9,"t":"Tko uklanja uho svoje da ne sluša Zakona, i molitva je njegova mrska."},{"v":10,"t":"Tko zavodi poštene na put zao, past će u jamu svoju, a pošteni će baštiniti sreću."},{"v":11,"t":"Bogat se čovjek čini sebi mudrim, ali će ga razuman siromah raskrinkati."},{"v":12,"t":"Velika je slava kad se raduju pravednici, a kad se dižu opaki, ljudi se kriju."},{"v":13,"t":"Tko skriva svoje grijehe, nema sreće, a tko ih ispovijeda i odriče ih se, milost nalazi."},{"v":14,"t":"Blago čovjeku uvijek bojaznu, jer čovjek okorjela srca zapada u nesreću."},{"v":15,"t":"Lav koji riče i gladan medvjed: takav je opak vladalac siromašnu narodu."},{"v":16,"t":"Nerazuman knez čini mnoga nasilja, a koji mrzi lakomost, dugo živi."},{"v":17,"t":"Onaj koga tišti krvna krivica, do groba bježi: ne zaustavljajte ga."},{"v":18,"t":"Spasava se tko živi pravedno, tko se koleba između dva puta, propada na jednom od njih."},{"v":19,"t":"Tko obrađuje svoju zemlju, nasitit će se kruha, a tko trči za tlapnjama, nasitit će se siromaštva."},{"v":20,"t":"Čestit čovjek stječe blagoslov, a tko hrli za bogatstvom, ne ostaje bez kazne."},{"v":21,"t":"Ne valja biti pristran na sudu, jer i za zalogaj kruha čovjek čini zlo."},{"v":22,"t":"Pohlepnik hrli za bogatstvom, a ne zna da će ga stići oskudica."},{"v":23,"t":"Tko kori čovjeka, nalazi poslije veću milost nego onaj koji laska jezikom."},{"v":24,"t":"Tko pljačka oca svoga i majku svoju i veli: “Nije grijeh”, drug je razbojniku."},{"v":25,"t":"Lakomac zameće svađu, a tko se uzda u Jahvu, uspjet će."},{"v":26,"t":"Bezuman je tko se uzda u svoje srce, a spasava se tko živi mudro."},{"v":27,"t":"Tko daje siromahu, ne trpi oskudicu; a tko odvraća oči svoje, bit će proklet."},{"v":28,"t":"Kad se dižu opaki, ljudi se kriju, a kad propadaju, tad se množe pravednici."}]},"29":{"hr":[{"v":1,"t":"Čovjek koji, po opomeni, ostaje tvrdoglav, u tren će se slomiti, i neće mu biti spasa."},{"v":2,"t":"Narod se veseli kad se množe pravednici, a puk uzdiše kad zavlada opaki."},{"v":3,"t":"Čovjek koji ljubi mudrost, veseli oca svoga, a koji se druži s bludnicama, rasipa imetak."},{"v":4,"t":"Kralj pravicom održava državu, a ruši je čovjek koji nameće daće."},{"v":5,"t":"Čovjek koji laska bližnjemu svome razapinje mrežu stopama njegovim."},{"v":6,"t":"U grijehu je zamka zlu čovjeku, a pravednik likuje i veseli se."},{"v":7,"t":"Pravednik razumije pravo malenih, a opaki ne shvaća spoznaju."},{"v":8,"t":"Podsmjevači uzbunjuju grad, a mudri stišavaju srdžbu."},{"v":9,"t":"Kad se mudrac parbi s bezumnikom, il' se srdio, il' se smijao, svejednako mira nema."},{"v":10,"t":"Krvopije mrze poštenoga, a pravednici mu se za život brinu."},{"v":11,"t":"Bezumnik izlijeva sav svoj gnjev, a mudrac susteže svoju srdžbu."},{"v":12,"t":"Ako vladalac posluša riječ lažljivu, sve mu sluge postaju opake."},{"v":13,"t":"Siromah se i gulikoža susreću: Jahve obojici prosvjetljuje oči."},{"v":14,"t":"Kralj koji sudi siromasima po istini ima prijesto čvrst dovijeka."},{"v":15,"t":"Šiba i ukor podaruju mudrost, a razuzdan mladić sramoti majku svoju."},{"v":16,"t":"Kad se množe opaki, množi se i grijeh, ali pravednici promatraju propast njihovu."},{"v":17,"t":"Ukori sina svoga, i zadovoljit će te i dati radost duši tvojoj."},{"v":18,"t":"Kad objave nema, narod se razuzda, a blago onome tko se drži Zakona!"},{"v":19,"t":"Samim se riječima sluga ne popravlja, jer se ne pokorava iako umom shvaća."},{"v":20,"t":"Jesi li vidio čovjeka brza na riječima? I bezumnik ima više nade nego on."},{"v":21,"t":"Tko mazi slugu svoga od djetinjstva bit će mu poslije neposlušan."},{"v":22,"t":"Gnjevljiv čovjek zameće svađu, a naprasit čovjek počini mnoge grijehe."},{"v":23,"t":"Oholost ponizuje čovjeka, a ponizan duhom postiže časti."},{"v":24,"t":"Tko s lupežom plijen dijeli, mrzi sebe samog: čuje proklinjanje i ništa ne otkriva."},{"v":25,"t":"Strah čovjeku postavlja zamku, a tko se uzda u Jahvu, nalazi okrilje."},{"v":26,"t":"Mnogi traže milost vladaočevu, ali Jahve dijeli pravdu svakome."},{"v":27,"t":"Nepravednik je mrzak pravednicima, a pravednik je mrzak opakima."}]},"30":{"hr":[{"v":1,"t":"Riječi Agura, sina Jakeova, iz Mase; proročanstvo njegovo za Itiela, za Itiela i Ukala."},{"v":2,"t":"Da, preglup sam da bih bio čovjek i nemam razbora čovječjeg."},{"v":3,"t":"Ne stekoh mudrosti i ne poznajem znanosti svetih!"},{"v":4,"t":"Tko uzađe na nebo i siđe? Tko uhvati vjetar u šake svoje? Tko sabra vode u plašt svoj? Tko postavi krajeve zemaljske? Kako se zove i kako mu se zove sin? Znaš li?"},{"v":5,"t":"Svaka je Božja riječ prokušana, štit onima koji se u nj uzdaju."},{"v":6,"t":"Ne dodaji ništa njegovim riječima, da te ne prekori i ne smatra lažljivim."},{"v":7,"t":"Za dvoje te molim, ne uskrati mi, dok ne umrem:"},{"v":8,"t":"udalji od mene licemjernu i lažnu riječ; ne daj mi siromaštva ni bogatstva: hrani me kruhom mojim dostatnim;"},{"v":9,"t":"inače bih, presitivši se, zatajio tebe i rekao: “Tko je Jahve?” Ili bih, osiromašivši, krao i oskvrnio ime Boga svojega."},{"v":10,"t":"Ne klevetaj sluge gospodaru njegovu, jer bi te mogao kleti i ti morao okajati."},{"v":11,"t":"Ima izrod koji kune oca svoga i ne blagoslivlje majke svoje!"},{"v":12,"t":"Izrod koji za se misli da je čist, a od kala svojeg nije opran!"},{"v":13,"t":"Izrod uznositih očiju koji visoko diže svoje trepavice!"},{"v":14,"t":"Izrod komu su zubi mačevi i očnjaci noževi da proždiru nesretnike na zemlji i siromahe među ljudima!"},{"v":15,"t":"Pijavica ima dvije kćeri: “Daj! Daj!” Postoje tri stvari nezasitne i četiri koje ne kažu: “Dosta!”"},{"v":16,"t":"Carstvo smrti, jalova utroba, zemlja nikad gasna vode i vatra koja nikad ne kaže: “Dosta!”"},{"v":17,"t":"Oko koje se ruga ocu i odriče posluh majci iskljuvat će potočni gavrani i izjesti mladi orlovi."},{"v":18,"t":"Troje mi je nedokučivo, a četvrto ne razumijem:"},{"v":19,"t":"put orlov po nebu, put zmijin po stijeni, put lađin posred mora i put muškarčev djevojci."},{"v":20,"t":"Takav je put preljubnice: najede se, obriše usta i veli: “Nisam sagriješila.”"},{"v":21,"t":"Od troga se zemlja ljulja, a četvrtoga ne može podnijeti:"},{"v":22,"t":"od roba kad postane kralj i kad se prostak kruha nasiti,"},{"v":23,"t":"od puštenice kad se uda i sluškinje kad istisne svoju gospodaricu."},{"v":24,"t":"Četvero je maleno na zemlji, ali mudrije od mudraca:"},{"v":25,"t":"mravi, nejaki stvorovi, koji sebi ljeti spremaju hranu;"},{"v":26,"t":"jazavci, stvorovi bez moći, što u stijeni grade sebi stan;"},{"v":27,"t":"skakavci, koji nemaju kralja, a svi idu u poretku;"},{"v":28,"t":"gušter, što se rukama hvata, a prodire u kraljevske palače."},{"v":29,"t":"Troje ima lijep korak, a četvero lijepo hodi:"},{"v":30,"t":"lav, junak među zvijerima, koji ni pred kim ne uzmiče;"},{"v":31,"t":"pijetao što se odvažno šeće među kokošima; jarac koji vodi stado; i kralj sa svojom vojskom."},{"v":32,"t":"Ako si ludovao oholeći se ili to svjesno činio, stavi ruku na usta."},{"v":33,"t":"Kad se mlijeko metÄe, izlazi maslac; kad se nos pritisne, poteče krv; kad se srdžba potisne, dobiva se spor."}]},"31":{"hr":[{"v":1,"t":"Riječ Lemuela, kralja Mase, kojima ga je učila majka njegova."},{"v":2,"t":"Ne, sine moj! Ne, sine srca mog! Ne, sine zavjeta mojih!"},{"v":3,"t":"Ne daj snage svoje ženama ni putova svojih zatiračima kraljeva."},{"v":4,"t":"Nije za kraljeve, Lemuele, ne pristaje kraljevima vino piti, ni glavarima piće opojno,"},{"v":5,"t":"da u piću ne zaborave zakona i prevrnu pravo nevoljnicima."},{"v":6,"t":"Dajte žestoko piće onomu koji će propasti i vino čovjeku komu je gorčina u duši:"},{"v":7,"t":"on će piti i zaboraviti svoju bijedu i neće se više sjećati svoje nevolje."},{"v":8,"t":"Otvaraj usta svoja za nijemoga i za pravo sviju nesretnika što propadaju."},{"v":9,"t":"Otvaraj usta svoja, sudi pravedno i pribavi pravo siromahu i nevoljniku."},{"v":10,"t":"Tko će naći ženu vrsnu? Više vrijedi ona nego biserje."},{"v":11,"t":"Muževljevo se srce uzda u nju i blagom neće oskudijevati."},{"v":12,"t":"Ona mu čini dobro, a ne zlo, u sve dane vijeka svojeg."},{"v":13,"t":"Pribavlja vunu i lan i vješto radi rukama marnim."},{"v":14,"t":"Ona je kao lađa trgovačka: izdaleka donosi kruh svoj."},{"v":15,"t":"Još za noći ona ustaje, hrani svoje ukućane i određuje posao sluškinjama svojim."},{"v":16,"t":"Opazi li polje, kupi ga; plodom svojih ruku sadi vinograd."},{"v":17,"t":"Opasuje snagom bedra svoja i živo miče rukama."},{"v":18,"t":"Vidi kako joj posao napreduje: noću joj se ne gasi svjetiljka."},{"v":19,"t":"Rukama se maša preslice i prstima drži vreteno."},{"v":20,"t":"Siromahu dlan svoj otvara, ruke pruža nevoljnicima."},{"v":21,"t":"Ne boji se snijega za svoje ukućane, jer sva čeljad ima po dvoje haljine."},{"v":22,"t":"Sama sebi šije pokrivače, odijeva se lanom i purpurom."},{"v":23,"t":"Muž joj je slavan na Vratima, gdje sjedi sa starješinama zemaljskim."},{"v":24,"t":"Platno tka i prodaje ga i pojase daje trgovcu."},{"v":25,"t":"Odjevena je snagom i dostojanstvom, pa se smije danu budućem."},{"v":26,"t":"Svoja usta mudro otvara i pobožan joj je nauk na jeziku."},{"v":27,"t":"Na vladanje pazi ukućana i ne jede kruha besposlice."},{"v":28,"t":"Sinovi njezini podižu se i sretnom je nazivaju, i muž njezin hvali je:"},{"v":29,"t":"“Mnoge su žene bile vrsne, ali ti ih sve nadmašuješ.”"},{"v":30,"t":"Lažna je ljupkost, tašta je ljepota: žena sa strahom Gospodnjim zaslužuje hvalu."},{"v":31,"t":"Plod joj dajte ruku njezinih i neka je na Vratima hvale djela njezina!"}]}},"ECC":{"1":{"hr":[{"v":1,"t":"Misli Propovjednika, Davidova sina, kralja u Jeruzalemu."},{"v":2,"t":"Ispraznost nad ispraznošću, veli Propovjednik, ispraznost nad ispraznošću, sve je ispraznost!"},{"v":3,"t":"Kakva je korist čovjeku od svega truda njegova kojim se trudi pod suncem?"},{"v":4,"t":"Jedan naraštaj odlazi, drugi dolazi, a zemlja uvijek ostaje."},{"v":5,"t":"Sunce izlazi, sunce zalazi i onda hiti svojem mjestu odakle izlazi."},{"v":6,"t":"Vjetar puše na jug i okreće se na sjever, kovitla sad ovamo sad onamo i vraća se u novom vrtlogu."},{"v":7,"t":"Sve rijeke teku u more i more se ne prepunja; odakle teku rijeke, onamo se vraćaju da ponovo počnu svoj tok."},{"v":8,"t":"Sve je mučno. Nitko ne može reći da se oči nisu do sita nagledale i uši dovoljno naslušale."},{"v":9,"t":"Što je bilo, opet će biti, i što se činilo, opet će se činiti, i nema ništa novo pod suncem."},{"v":10,"t":"Ima li išta o čemu bi se moglo reći: “Gle, ovo je novo!” Sve je već davno prije nas postojalo."},{"v":11,"t":"Samo, od prošlosti ne ostade ni spomena, kao što ni u budućnosti neće biti sjećanja na ono što će poslije doći."},{"v":12,"t":"Ja, Propovjednik, bijah kralj nad Izraelom u Jeruzalemu."},{"v":13,"t":"I trudih se da mudrošću istražim i dokučim sve što biva pod nebom; o, kako mučnu zadaću zadade Bog sinovima ljudskim."},{"v":14,"t":"Vidjeh sve što se čini pod suncem: kakve li ispraznosti i puste tlapnje!"},{"v":15,"t":"Što je krivo, ne može se ispraviti; čega nema, izbrojiti se ne može."},{"v":16,"t":"Rekoh onda sam sebi: “Gle, stekao sam veću mudrost nego bilo tko od mojih prethodnika u Jeruzalemu. Duh moj sabrao je golemu mudrost i znanje.”"},{"v":17,"t":"Mudrost pomnjivo proučih, a tako i glupost i ludost, ali sam spoznao da je to pusta tlapnja."},{"v":18,"t":"Mnogo mudrosti - mnogo jada; što više znanja, to više boli."}]},"2":{"hr":[{"v":1,"t":"Tad rekoh u srcu svom: “Daj da okušam užitak i vidim što naslada pruža” - ali gle: i to je ispraznost!"},{"v":2,"t":"O smijehu rekoh: “Ludost je”; o užitku: “Čemu valja?”"},{"v":3,"t":"Odlučih tijelo krijepiti vinom, a srce posvetiti mudrosti; poželjeh prigrliti i ludost, kako bih spoznao usrećava li ljude ono što pod nebesima čine za izbrojenih dana svojega života."},{"v":4,"t":"Učinih velika djela: sazidah sebi palače, zasadih vinograde;"},{"v":5,"t":"uredih perivoje i voćnjake, nasadih u njima voćke svakojake."},{"v":6,"t":"Načinih jezera da plodna sadišta natapam."},{"v":7,"t":"Nakupovah robova i robinja, imadoh i sluge domaće, a tako i stada krupne i sitne stoke više no itko prije mene u Jeruzalemu."},{"v":8,"t":"Nagomilah srebro i zlato i blago kraljeva i pokrajina, nabavih pjevače i pjevačice i svakoga raskošja ljudskog, sve škrinju na škrinji."},{"v":9,"t":"I postadoh tako velik, veći no bilo tko prije mene u Jeruzalemu; a nije me ni mudrost moja ostavila."},{"v":10,"t":"I što god su mi oči poželjele, nisam im uskratio, niti branih srcu svojemu kakva veselja, već se srce moje veselilo svakom trudu mojem, i takva bi nagrada svakom mojem naporu."},{"v":11,"t":"A onda razmotrih sva svoja djela, sve napore što uložih da do njih dođem - i gle, sve je to opet ispraznost i pusta tlapnja! I ništa nema valjano pod suncem."},{"v":12,"t":"Okrenuh zatim misao svoju mudrosti, gluposti i ludosti. Što, na priliku, čini kraljev nasljednik? Ono što je već učinjeno."},{"v":13,"t":"I spoznadoh da je bolja mudrost od ludosti, kao što je svjetlost bolja od tame."},{"v":14,"t":"Mudracu su oči u glavi, a bezumnik luta u tami. Ali također znam da obojicu stiže ista kob."},{"v":15,"t":"Zato rekoh u sebi: “Kakva je sudbina luđaku, takva je i meni. Čemu onda žudjeti za mudrošću?” I rekoh u srcu: “I to je ispraznost!”"},{"v":16,"t":"Jer trajna spomena nema ni mudru ni bezumniku: obojicu će poslije nekog vremena prekriti zaborav! I, jao, mudrac mora umrijeti kao i bezumnik."},{"v":17,"t":"Omrznuh život, jer mi se učini mučnim sve što se zbiva pod suncem: sve je ispraznost i pusta tlapnja."},{"v":18,"t":"Zamrzih sve za što sam se pod suncem trudio i što sad ostavljam svome nasljedniku."},{"v":19,"t":"Tko zna hoće li on biti mudar ili lud? Pa ipak on će biti gospodar sve moje muke u koju uložih sav svoj napor i mudrost pod suncem. I to je ispraznost."},{"v":20,"t":"I stao sam srcem očajavati zbog velikog napora kojim sam se trudio pod suncem."},{"v":21,"t":"Jer čovjek se trudi mudro i umješno i uspješno, pa sve to mora ostaviti u baštinu drugomu koji se oko toga nije uopće trudio. I to je ispraznost i velika nevolja."},{"v":22,"t":"Jer što on dobiva za sav svoj napor i trud koji je pod suncem podnio?"},{"v":23,"t":"Jer svi su njegovi dani doista mukotrpni, poslovi mu puni brige; čak ni noću ne miruje srce njegovo. I to je ispraznost."},{"v":24,"t":"Nema čovjeku druge sreće već jesti i piti i biti zadovoljan svojim poslom. I to je, vidim, dar Božje ruke."},{"v":25,"t":"Jer tko bi mogao jesti, tko li nezadovoljan biti, osim po njemu."},{"v":26,"t":"Mudrost, spoznaju, radost on daruje onom tko mu je po volji, a grešniku nameće zadaću da sabira i skuplja za onoga tko je po volji Bogu. I to je ispraznost i pusta tlapnja."}]},"3":{"hr":[{"v":1,"t":"Sve ima svoje doba i svaki posao pod nebom svoje vrijeme."},{"v":2,"t":"Vrijeme rađanja i vrijeme umiranja; vrijeme sađenja i vrijeme čupanja posađenog."},{"v":3,"t":"Vrijeme ubijanja i vrijeme liječenja; vrijeme rušenja i vrijeme građenja."},{"v":4,"t":"Vrijeme plača i vrijeme smijeha; vrijeme tugovanja i vrijeme plesanja."},{"v":5,"t":"Vrijeme bacanja kamenja i vrijeme sabiranja kamenja; vrijeme grljenja i vrijeme kad se ostavlja grljenje."},{"v":6,"t":"Vrijeme traženja i vrijeme gubljenja; vrijeme čuvanja i vrijeme odbacivanja."},{"v":7,"t":"Vrijeme deranja i vrijeme š§ijenja; vrijeme šutnje i vrijeme govorenja."},{"v":8,"t":"Vrijeme ljubljenja i vrijeme mržnje; vrijeme rata i vrijeme mira."},{"v":9,"t":"Koja je posleniku korist od njegovih napora?"},{"v":10,"t":"Razmišljam o mučnoj zadaći što je Bog zadade sinovima ljudskim."},{"v":11,"t":"Sve što on čini prikladno je u svoje vrijeme; ali iako je dopustio čovjeku uvid u vjekove, čovjek ne može dokučiti djela koja Boga čini od početka do kraja."},{"v":12,"t":"Znam da nije druge sreće čovjeku osim da se veseli i čini dobro za svojega života."},{"v":13,"t":"I kad čovjek jede i pije i uživa u svojem radu, i to je Božji dar."},{"v":14,"t":"I znam da sve što Bog čini, čini za stalno. Tome se ništa dodati ne može niti mu se može oduzeti; a Bog čini tako da ga se boje."},{"v":15,"t":"Što biva, već bijaše, i što će biti, već je bilo; a Bog obnavlja što je prohujalo."},{"v":16,"t":"Još vidim kako pod suncem umjesto pravice vlada nepravda i umjesto pravednika zločinac."},{"v":17,"t":"Zato rekoh u sebi: “Bog će suditi i pravedniku i zločincu, jer ovdje ima vrijeme za svaku namjeru i čin.”"},{"v":18,"t":"Još rekoh u sebi: “Ljudi se ponašaju tako da Bog može pokazati kakvi su uistinu, da su jedni drugima poput zvijeri.”"},{"v":19,"t":"Jer zaista, kob ljudi i zvijeri jedna je te ista. Kako ginu oni, tako ginu i one; i dišu jednakim dahom, i čovjek ničim ne nadmašuje zvijer, jer sve je ispraznost."},{"v":20,"t":"I jedni i drugi odlaze na isto mjesto; svi su postali od praha i u prah se vraćaju."},{"v":21,"t":"Tko zna da li dah ljudski uzlazi gore, a dah zvijeri silazi dolje k zemlji?"},{"v":22,"t":"Uviđam da čovjeku druge sreće nema osim radosti u svome djelu, jer to je ljudska sudbina. A tko će ga dovesti do toga da dozna što će biti poslije njega?"}]},"4":{"hr":[{"v":1,"t":"Opet stadoh promatrati sva nasilja koja se čine pod suncem, i gle, suze potlačenih, i nikog nema da ih utre; i nasilje iz tlačiteljske ruke, a zaštitnika niotkuda."},{"v":2,"t":"Zato sretnima smatram mrtve koji su već pomrli; sretniji su od živih što još žive."},{"v":3,"t":"A od obojih je sretniji onaj koji još nije postao, koji nije vidio zlih djela što se čine pod suncem."},{"v":4,"t":"Nadalje iskusih da svaki napor i svaki uspjeh pribavlja čovjeku zavist njegova bližnjeg. I to je ispraznost i pusta tlapnja."},{"v":5,"t":"Bezumnik prekriži ruke i izjeda sebe."},{"v":6,"t":"Bolja je puna šaka u miru nego obje pregršti mučna rada i puste tlapnje."},{"v":7,"t":"I još jednu opazih ispraznost pod suncem:"},{"v":8,"t":"Čovjek potpun samac - bez sina, bez brata, i opet nema kraja njegovu trudu; oči mu se ne mogu nasititi blaga; a ne misli: za koga se mučim i uskraćujem dobro sebi? I to je ispraznost i zla briga."},{"v":9,"t":"Bolje je dvojici nego jednome, jer imaju bolju plaću za svoj trud."},{"v":10,"t":"Padne li jedan, drugi će ga podići; a teško jednomu! Ako padne, nema nikoga da ga podigne."},{"v":11,"t":"Pa ako se i spava udvoje, toplije je; a kako će se samac zagrijati?"},{"v":12,"t":"I ako tko udari na jednoga, dvojica će mu se oprijeti; i trostruko se uže ne kida brzo."},{"v":13,"t":"Bolji je mladić siromašan a mudar nego kralj star a lud, koji više ne zna za savjet."},{"v":14,"t":"Jer mladić može izići iz tamnice i postati kraljem, iako se rodio kao prosjak u svom kraljevstvu."},{"v":15,"t":"Opazih kako svi koji žive i hode pod suncem pristaju uz mladića, uz nastupnika koji ga naslijedi."},{"v":16,"t":"On stupa na čelo bezbrojnih podanika i kasniji se naraštaji ne mogahu zbog njega radovati. I to je zacijelo ispraznost i pusta tlapnja."},{"v":17,"t":"Kad odlaziš u Božji dom, pazi na korake svoje. Priđi da mogneš čuti - žrtva je valjanija nego prinos luđaka, jer oni i ne znaju da čine zlo."}]},"5":{"hr":[{"v":1,"t":"Ne nagli ustima svojim i ne žuri se s riječima pred Bogom, jer je Bog na nebu, a ti si na zemlji; zato štedi svoje riječi."},{"v":2,"t":"San dolazi od mnogih briga, a lud govor od mnoštva riječi."},{"v":3,"t":"Kad zavjetuješ štogod Bogu, odmah to izvrši, jer njemu nisu mili bezumnici. Zato ispuni svaki svoj zavjet."},{"v":4,"t":"Bolje je ne zavjetovati, nego zavjetovati a ne izvršiti zavjeta."},{"v":5,"t":"Ne daj ustima svojim da te navode na grijeh i ne reci kasnije pred anđelom da je bilo nehotice. Zašto pružati Bogu priliku da se srdi na riječ tvoju i uništi djelo tvojih ruku?"},{"v":6,"t":"Koliko sanja, toliko i ispraznosti; mnogo riječi - isprazna tlapnja. Zato boj se Boga."},{"v":7,"t":"Ako vidiš gdje tlače siromaha i gaze pravo i pravicu u zemlji, ne čudi se tomu, jer nad visokim straži viši, a nad njim najviši."},{"v":8,"t":"Korist zemlje je nada sve; i kralj ovisi o zemljištu."},{"v":9,"t":"Tko novce ljubi, nikad ih dosta nema; tko bogatstvo ljubi, nikad mu dosta probitka. I to je ispraznost."},{"v":10,"t":"Gdje je mnogo bogatstva, mnogo je i gotovana, pa kakva je korist od toga gospodaru, osim što ga očima gleda?"},{"v":11,"t":"Sladak je dan radiši, jeo malo ili mnogo, dok bogatstvo ne da bogatašu zaspati."},{"v":12,"t":"I vidjeh teško zlo pod suncem: skupljeno blago što je na propast svojemu vlasniku."},{"v":13,"t":"Jer zlom nezgodom propadne takvo bogatstvo te sinu što mu se rodi ne ostane ništa."},{"v":14,"t":"Gol je izašao iz utrobe majke svoje i tako će gol i otići kakav je i došao; ništa nema od svega svojeg truda da ponese."},{"v":15,"t":"I to je teško zlo što tako odlazi kako je i došao; pa kakva mu je korist što se u vjetar mučio."},{"v":16,"t":"Sve svoje dane živi u tami, nevolji, brizi, bolesti i srdžbi."},{"v":17,"t":"Ovo, stoga, zaključujem: prava je sreća čovjeku jesti i piti i biti zadovoljan sa svim svojim trudom kojim se muči pod suncem za kratka vijeka koji mu je dao Bog, jer takva mu je sudbina dosuđena."},{"v":18,"t":"Pa ako je čovjeku Bog dao bogatstvo i imanje da ih uživa i bude zadovoljan svojim djelom - i to je dar od Boga."},{"v":19,"t":"Jer tada barem ne misli mnogo na dane svog života, kad mu Bog daje da mu se srce veseli."}]},"6":{"hr":[{"v":1,"t":"I vidjeh: ima još jedno zlo pod suncem i teško tišti ljude."},{"v":2,"t":"Nekomu Bog udijeli bogatstvo i blago i počasti te ima sve što mu duša poželi, ali mu ne udijeli da to i uživa, nego uživa tuđinac. To je ispraznost i grdna nevolja."},{"v":3,"t":"I velim: bolje je nedonošče od onoga koji bi rodio stotinu djece i živio mnogo godina, a sam se ne bi naužio dobra niti bi imao pogreba;"},{"v":4,"t":"jer je nedonošče uzalud došlo i u tamu otišlo i ime mu je tamom pokriveno;"},{"v":5,"t":"sunca čak ne vidje niti spozna - a spokojnije je od onoga."},{"v":6,"t":"Pa kad bi takav živio i dvije tisuće godina, a svojeg dobra ne bi uživao, zar ne odlaze obojica jednako na isto mjesto?"},{"v":7,"t":"Čovjek se trudi samo da bi jeo, a želudac njegov nikad da se nasiti."},{"v":8,"t":"Jer po čemu je mudrac bolji od luđaka i što reći o siromahu koji se umije držati pred ljudima?"},{"v":9,"t":"Bolje je očima vidjeti nego duhom lutati. I to je ispraznost i pusta tlapnja."},{"v":10,"t":"Što je već bilo, ime ima; i zna se što je čovjek; i on se ne može parbiti s jačim od sebe."},{"v":11,"t":"Što više riječi, to veća ispraznost svega, i koja je od toga korist čovjeku?"},{"v":12,"t":"Tko zna što je dobro čovjeku u životu njegovu, za ono malo dana koje tako isprazno živi, koji mu prolaze kao sjena? Tko će kazati čovjeku što će biti poslije njega pod suncem?"}]},"7":{"hr":[{"v":1,"t":"Bolji je dobar glas nego skupocjeno ulje, i smrtni dan nego dan rođenja."},{"v":2,"t":"Bolje je ići u kuću gdje je žalost nego u kuću gdje je gozba, jer ondje je kraj svakoga čovjeka, i tko je živ, nek' primi k srcu!"},{"v":3,"t":"Bolji je jad nego smijeh, jer pod žalosnim licem srce je radosno."},{"v":4,"t":"Srce je mudrih ljudi u kući žalosti, a srce bezumnih u kući veselja."},{"v":5,"t":"Bolje je poslušati ukor mudra čovjeka negoli slušati hvalospjev luđaka."},{"v":6,"t":"Jer kao prasak trnja ispod kotla, takav je smijeh luđaka, i to je ispraznost."},{"v":7,"t":"Jer smijeh od mudraca čini luđaka i veselje kvari srce."},{"v":8,"t":"Bolji je svršetak stvari nego njezin početak i bolja je strpljivost od oholosti."},{"v":9,"t":"Ne nagli u srdžbu, jer srdžba počiva u srcu luđaka."},{"v":10,"t":"Ne pitaj zašto su negdašnja vremena bila bolja od ovih, jer to nije mudro pitanje."},{"v":11,"t":"Mudrost je dragocjena baština i probitak onima na koje sunce sja."},{"v":12,"t":"Jer kao što je novac zaštita, tako je i mudrost; a prednost je mudrosti u tome što izbavlja onoga tko je ima."},{"v":13,"t":"Pogledaj djela Božja; tko može ispraviti što je on iskrivio?"},{"v":14,"t":"U sretan dan uživaj sreću, a u zao dan razmišljaj: Bog je stvorio jedno kao i drugo - da čovjek ne otkrije ništa od svoje budućnosti."},{"v":15,"t":"Svašta vidjeh u svojemu ništavnom životu: pravednik propada unatoč svojoj pravednosti, a bezbožnik i dalje živi unatoč svojoj bezbožnosti."},{"v":16,"t":"Ne budi prepravedan i ne budi premudar; zašto da se uništavaš?"},{"v":17,"t":"Ne budi preopak i ne budi lud; zašto bi umro prije vremena?"},{"v":18,"t":"Dobro je da držiš jedno, ali ni drugo ne puštaj iz ruke, jer tko se boji Boga, izbavlja se od svega."},{"v":19,"t":"Mudrost mudraca veću moć daje gradu nego deset mogućnika."},{"v":20,"t":"Na zemlji nema pravednika koji, čineći dobro, ne bi nikad sagriješio."},{"v":21,"t":"I još jedno: nemoj se obazirati na govorkanje; čut ćeš možda da te sluga tvoj proklinjao;"},{"v":22,"t":"a zna tvoje srce kako si i ti često druge proklinjao."},{"v":23,"t":"Sve sam to mudrošću iskušao. Mislio sam da sam mudar, ali mi je mudrost bila nedokučiva."},{"v":24,"t":"Ono što jest, daleko je i duboko, tako duboko - tko da i pronađe?"},{"v":25,"t":"I još jednom pokušah istražiti i shvatiti mudrost i smisao, da spoznam opačinu kao ludost, a ludost kao bezumlje."},{"v":26,"t":"Otkrih da ima nešto gorče od smrti - žena, ona je zamka, srce joj je mreža, a ruke okovi; tko je Bogu drag, izmiče joj, a grešnik je njezin sužanj."},{"v":27,"t":"Eto, to sam sve u svemu otkrio, veli Propovjednik."},{"v":28,"t":"I još sam tražio, ali bez uspjeha. Nađoh čovjeka - jednog od tisuću, a žene ne nađoh među svima nijedne."},{"v":29,"t":"Otkrih ovo: Bog stvori čovjeka jednostavnim, a on snuje nebrojene spletke."}]},"8":{"hr":[{"v":1,"t":"Tko je kao mudrac? Tko još umije tumačiti stvari? Mudrost čovjeku razvedruje lice i mijenja njegov namršteni lik."},{"v":2,"t":"Zato velim: slušaj kraljevu zapovijed zbog Božje zakletve."},{"v":3,"t":"Ne nagli da je prekršiš: ne budi tvrdoglav kad razlog nije dobar, jer on čini kako mu odgovara."},{"v":4,"t":"Jer kraljeva je riječ najjača, i tko ga smije pitati: “Što činiš?”"},{"v":5,"t":"Tko se drži zapovijedi, ne poznaje nevolju, i mudrac zna za vrijeme i sud."},{"v":6,"t":"Jer postoji vrijeme i sud za sve, i čovjeka veoma tereti nedjelo njegovo"},{"v":7,"t":"jer on ne zna što će biti; a tko mu može kazati kad će što biti?"},{"v":8,"t":"Vjetar nitko ne može svladati, niti gospodariti nad danom smrtnim, niti ima odgode u ratu; niti opačina izbavlja onoga koji je čini."},{"v":9,"t":"Sve ovo vidjeh pazeći na sve što se čini pod suncem, kad čovjek vlada nad čovjekom na njegovu nesreću."},{"v":10,"t":"Dalje vidjeh kako opake nose na groblje, i ljudi iz svetog mjesta izlaze da ih slave zbog toga što su tako činili. I to je ispraznost."},{"v":11,"t":"Kad nema brze osude za zlo djelo, ljudsko je srce sklono činiti zlo."},{"v":12,"t":"I grešnik koji čini zlo i sto puta, dugo živi. Ja ipak znam da će biti sretni oni koji se boje Boga jer ga se boje."},{"v":13,"t":"Ali opak čovjek neće biti sretan i neće produljivati svoje dane ni kao sjena jer se ne boji Boga."},{"v":14,"t":"Ali je na zemlji ispraznost te pravednike stiže sudbina opakih, a opake sudbina pravednika. Velim: i to je ispraznost."},{"v":15,"t":"Zato slavim veselje, jer nema čovjeku sreće pod suncem nego u jelu, pilu i nasladi. I to neka ga prati u njegovoj muci za života koji mu Bog dade pod suncem."},{"v":16,"t":"Poslije svih napora da dokučim mudrost, pokušah spoznati što se radi na zemlji. Uistinu, čovjek ne nalazi spokojstva ni danju ni noću."},{"v":17,"t":"Promatram cjelokupno djelo Božje: i odista - nitko ne može dokučiti ono što se zbiva pod suncem. Jer ma koliko se čovjek trudio da otkrije, nikad ne može otkriti. Pa ni mudrac to ne može otkriti, iako misli da zna."}]},"9":{"hr":[{"v":1,"t":"Razmišljah o svemu tome i shvatih kako su i pravednici i mudraci, sa djelima svojim, u Božjoj ruci; i čovjek ne razumije ni ljubavi ni mržnje, i njemu su obje ispraznost."},{"v":2,"t":"Svima je ista kob, pravednomu kao i opakom, čistomu i nečistomu, onomu koji žrtvuje kao i onomu koji ne žrtvuje; jednako dobru kao i grešniku, onomu koji se zaklinje kao i onomu koji se boji zakletve."},{"v":3,"t":"Najgore je od svega što biva pod suncem ovo: ista je kob svima, ljudsko je srce puno zla, ludost je u srcima ljudi dok žive, a potom se pridružuju mrtvima."},{"v":4,"t":"Jer onaj tko je među živima, ima nade: i živ pas više vrijedi nego mrtav lav."},{"v":5,"t":"Živi barem znaju da će umrijeti, a mrtvi ne znaju ništa niti imaju više nagrade, jer se zaboravlja i spomen na njih."},{"v":6,"t":"Davno je nestalo i njihove ljubavi, i mržnje, i zavisti, i više nemaju udjela ni u čem što biva pod suncem."},{"v":7,"t":"Zato s radošću jedi svoj kruh i vesela srca pij svoje vino, jer se Bogu već prije svidjelo tvoje djelo."},{"v":8,"t":"U svako doba nosi haljine bijele i ulja nek' ne ponestane na tvojoj glavi."},{"v":9,"t":"Uživaj život sa ženom koju ljubiš u sve dane svojega ispraznog vijeka koji ti Bog daje pod suncem, jer to je tvoj udio u životu i u trudu kojim se trudiš pod suncem."},{"v":10,"t":"I što god nakaniš učiniti, učini dok možeš, jer nema ni djela, ni umovanja, ni spoznaje, ni mudrosti u Podzemlju u koje ideš."},{"v":11,"t":"Osim toga, vidjeh pod suncem: ne dobivaju trku hitri, ni boj hrabri; nema kruha za mudraca, ni bogatstva za razumne, ni milosti za učene, jer vrijeme i kob sve ih dostiže."},{"v":12,"t":"Čovjek ne zna svoga časa: kao ribe ulovljene u podmukloj mreži, i kao ptice u zamku uhvaćene, tako se hvataju sinovi ljudski u vrijeme nevolje koja ih iznenada spopada."},{"v":13,"t":"Još vidjeh pod suncem i ovu “mudrost” koja mi se učini velikom:"},{"v":14,"t":"Bi jedan malen grad i u njem malo ljudi, a na nj udari velik kralj, opkoli ga i podiže oko njega velike opsadne tornjeve."},{"v":15,"t":"Ali se u njemu nađe čovjek siromah mudar koji spasi grad svojom mudrošću, a poslije se nitko nije sjećao toga čovjeka."},{"v":16,"t":"Ipak ja velim: bolja je mudrost nego jakost, ali se ne cijeni mudrost siromaha i ne slušaju njegove riječi."},{"v":17,"t":"Blage se riječi mudraca bolje čuju nego vika zapovjednika nad luđacima."},{"v":18,"t":"Mudrost više vrijedi nego bojno oružje, ali jedan jedini grešnik pokvari mnogo dobra."}]},"10":{"hr":[{"v":1,"t":"Uginula muha usmrdi mirisno ulje, a i malo ludosti jače je od mudrosti i časti."},{"v":2,"t":"Mudrac kroči pravim putem, a luđak krivim."},{"v":3,"t":"Dovoljno je da luđak pođe putem: kako razbora nema, svakomu pokazuje da je lud."},{"v":4,"t":"Ako se na te digne vladaočev gnjev, ne ostavljaj svoga mjesta, jer blagost sprečava velike grijehe."},{"v":5,"t":"Ima zlo što ga vidjeh pod suncem kao prestupak koji dolazi od vladaoca:"},{"v":6,"t":"ludost se podiže na najviša mjesta, a veliki zauzimaju niske položaje."},{"v":7,"t":"Vidjeh sluge na konjima, a knezove gdje idu pješice kao sluge."},{"v":8,"t":"Tko jamu kopa, u nju pada; i tko ruši zid, ujeda ga zmija."},{"v":9,"t":"Tko lomi kamenje, ono ga ranjava; tko cijepa drva, može nastradati."},{"v":10,"t":"Kad zatupi željezo i oštrica mu nije nabrušena, tada treba više snage; a nagrada mudrosti je uspjeh."},{"v":11,"t":"Ako zmija ujede prije čaranja, ništa onda opčaratelj ne koristi."},{"v":12,"t":"Pune su miline riječi iz usta mudraca, a bezumnika upropašćuju njegove usne."},{"v":13,"t":"On počinje svoje besjede ludošću i svršava ih potpunim bezumljem."},{"v":14,"t":"Luđak previše govori: čovjek ne poznaje budućnost, i tko mu može kazati što će poslije njega biti?"},{"v":15,"t":"Luđake mori njihov trud; tko ne zna puta, ne može u grad."},{"v":16,"t":"Jao tebi, zemljo, kad ti je kralj premlad i knezovi se već ujutro goste."},{"v":17,"t":"Blago tebi, zemljo, kad ti je kralj plemenit i knezovi ti u svoje vrijeme blaguju da se okrijepe, a ne da se opiju."},{"v":18,"t":"S lijenosti se ugiblju grede, zbog nebrige prokišnjava kuća."},{"v":19,"t":"Ali su gozbe radi zabave i vino uveseljava život, a novci pribavljaju sve."},{"v":20,"t":"Ni u svojoj misli ne kuni kralja, ni u svojoj ložnici ne kuni bogataša, jer će ptice odnijeti glas i kleveta lako okrilati."}]},"11":{"hr":[{"v":1,"t":"Baci kruh svoj na vodu i naći ćeš ga poslije mnogo vremena."},{"v":2,"t":"Podijeli sedmorici ili osmorici, jer ne znaš kakvo će zlo zadesiti zemlju."},{"v":3,"t":"Kad se oblaci napune kišom, prosiplju je na zemlju, a padne li drvo na jug ili na sjever, svejedno: gdje padne, ondje i ostaje."},{"v":4,"t":"Tko pazi na vjetar, ne sije, i tko gleda na oblake, ne žanje."},{"v":5,"t":"Kao što ne znaš koji je put vjetru ni kako postaju kosti u utrobi trudne žene, tako ne znaš ni djela Boga koji sve tvori."},{"v":6,"t":"Ujutro sij svoje sjeme, a navečer nek' ti ruka ne počiva. Jer ne znaš da li će biti bolje ovo ili ono, ili će oboje biti jednako dobro."},{"v":7,"t":"Ljupka je svjetlost i ugodno je očima vidjeti sunce."},{"v":8,"t":"Ali ako čovjek živi i mnogo godina, neka se uvijek veseli, a neka se sjeti da će tamnih dana biti mnogo. Ispraznost je sve što će doći."},{"v":9,"t":"Zato se raduj, mladiću, za svoje mladosti, i veseli se u danima svoga mladenaštva; idi putovima svoga srca i slijedi želje svojih očiju; ali znaj da će ti za sve to suditi Bog."},{"v":10,"t":"Ukloni dakle jad iz svoga srca i udalji bol od svojega tijela. Ali je isprazna i mladost i doba tamnih kosa."}]},"12":{"hr":[{"v":1,"t":"I sjećaj se svoga Stvoritelja u danima svoje mladosti prije nego dođu zli dani i prispiju godine kad ćeš reći: “Ne mile mi se.”"},{"v":2,"t":"Prije nego potamni sunce i svjetlost, mjesec i zvijezde, i vrate se oblaci iza kiše."},{"v":3,"t":"U dan kad zadrhte čuvari kuće i pognu se junaci, i dosađuju se mlinarice jer ih je premalo, i potamne oni koji gledaju kroz prozore;"},{"v":4,"t":"kad se zatvore ulična vrata, oslabi šum mlina, kad utihne pjev ptice i zamru zvuci pjesme."},{"v":5,"t":"Kad je put uzbrdo muka i svaki izlazak prijetnja; a badem je u cvatu, i skakavac ne skače više, i koprov plot puca, jer čovjek ide u svoj vječni dom! A narikače već se kreću ulicama."},{"v":6,"t":"Prije nego se prekine srebrna vrpca i zlatna se svjetiljka razbije i razlupa se vrč na izvoru i slomi točak na bunaru;"},{"v":7,"t":"i vrati se prah u zemlju kao što je iz nje i došao, a duh se vrati Bogu koji ga je dao."},{"v":8,"t":"Ispraznost nad ispraznostima, veli Propovjednik, sve je ispraznost."},{"v":9,"t":"A osim toga što je sam Propovjednik bio mudar, on je i narod učio mudrosti te je odmjerio, ispitao i sastavio mnogo mudrih izreka."},{"v":10,"t":"Ujedno se Propovjednik trudio pronaći prikladne riječi i izravno izraziti istinu."},{"v":11,"t":"Besjede su mudrih ljudi kao ostani i kao pobodeni kolci: pastir se njima služi na dobro svojega stada."},{"v":12,"t":"I na kraju, sine moj, znaj da je neizmjerno mnogo truda potrebno da se napiše knjiga i da mnogo učenje umara tijelo."},{"v":13,"t":"Čujmo svemu završnu riječ: “Boj se Boga, izvršuj njegove zapovijedi, jer - to je sav čovjek.”"},{"v":14,"t":"Jer sva će skrivena djela, bila dobra ili zla, Bog izvesti na sud."}]}},"SNG":{"1":{"hr":[{"v":1,"t":"Salomonova Pjesma nad pjesmama"},{"v":2,"t":"Poljubi me poljupcem usta svojih, ljubav je tvoja slađa od vina."},{"v":3,"t":"Miris najboljih mirodija, ulje razlito ime je tvoje, zato te ljube djevojke."},{"v":4,"t":"Povuci me za sobom, bježimo! Kralj me uveo u odaje svoje. Igrat ćemo se i radovati zbog tebe, slavit ćemo ljubav tvoju više nego vino. Pravo je da te ljube."},{"v":5,"t":"Crna sam ali lijepa, kćeri jeruzalemske, kao šatori kedarski, kao zavjese Salomonove."},{"v":6,"t":"Ne gledajte što sam garava, to me sunce opalilo. Sinovi majke moje rasrdili se na mene, postavili me da čuvam vinograde; a svog vinograda, koji je u meni, nisam čuvala."},{"v":7,"t":"Reci mi, ti koga ljubi duša moja, gdje paseš, gdje se u podne odmaraš, da ne lutam, tražeći te, oko stada tvojih drugova."},{"v":8,"t":"Ako ne znaš, o najljepša među ženama, izađi i slijedi tragove stada i pasi kozliće svoje oko pastirskih koliba."},{"v":9,"t":"Usporedio bih te s konjima pod kolima faraonovim, o prijateljice moja."},{"v":10,"t":"Lijepi su obrazi tvoji među naušnicama, vrat tvoj pod ogrlicama."},{"v":11,"t":"Učinit ćemo za tebe zlatne naušnice s privjescima srebrnim."},{"v":12,"t":"- Dok se kralj odmara na svojim dušecima, (tada) nard moj miriše."},{"v":13,"t":"Dragi mi je moj stručak smirne što mi među grudima počiva."},{"v":14,"t":"Dragi mi je moj grozd ciprov u vinogradima engedskim."},{"v":15,"t":"- Gle, kako si lijepa, prijateljice moja, gle, kako si lijepa, imaš oči kao golubica."},{"v":16,"t":"- Gle, kako si lijep, dragi moj, gle, kako si mio. Zelenilo je postelja naša."},{"v":17,"t":"- Grede kuća naših cedri su, a natkrovlje čempresi."}]},"2":{"hr":[{"v":1,"t":"- Ja sam cvijet šaronski, ljiljan u dolu."},{"v":2,"t":"- Što je ljiljan među trnjem, to je prijateljica moja među djevojkama."},{"v":3,"t":"- Što je jabuka među šumskim stablima, to je dragi moj među mladićima; bila sam željna hlada njezina i sjedoh, plodovi njeni slatki su grlu mome."},{"v":4,"t":"Uveo me u odaje vina i pokrio me zastavom ljubavi."},{"v":5,"t":"Okrijepite me kolačima, osvježite jabukama, jer sam bolna od ljubavi."},{"v":6,"t":"Njegova mi je lijeva ruka pod glavom, a desnom me grli."},{"v":7,"t":"- Kćeri jeruzalemske, zaklinjem vas srnama i košutama poljskim, ne budite, ne budite ljubav moju dok sama ne bude htjela!"},{"v":8,"t":"Glas dragoga moga! Evo ga, dolazi, prelijeće brda, preskakuje brežuljke."},{"v":9,"t":"Dragi je moj kao srna, on je kao jelenče. Evo ga za našim zidom, gleda kroz prozore, zaviruje kroz rešetke."},{"v":10,"t":"Dragi moj podiže glas i govori mi: “Ustani, dragano moja, ljepoto moja, i dođi,"},{"v":11,"t":"jer evo, zima je već minula, kiša je prošla i nestala."},{"v":12,"t":"Cvijeće se po zemlji ukazuje, vrijeme pjevanja dođe i glas se grličin čuje u našem kraju."},{"v":13,"t":"Smokva je izbacila prve plodove, vinograd, u cvatu, miriše. Ustani, dragano moja, ljepoto moja i dođi."},{"v":14,"t":"Golubice moja, u spiljama kamenim, u skrovištima vrletnim, daj da ti vidim lice i da ti čujem glas, jer glas je tvoj ugodan i lice je tvoje krasno.”"},{"v":15,"t":"Pohvatajte lisice, male lisice što oštećuju vinograde, naše vinograde u cvatu."},{"v":16,"t":"Dragi moj pripada meni, a ja njemu, on pase među ljiljanima."},{"v":17,"t":"Prije nego dan izdahne i sjene se spuste, vrati se, dragi moj: budi lagan kao srna, kao lane na gori Beteru."}]},"3":{"hr":[{"v":1,"t":"Po ležaju svome, u noćima, tražila sam onoga koga ljubi duša moja, tražila sam ga, ali ga nisam našla."},{"v":2,"t":"Ustat ću dakle i optrčati grad, po ulicama i trgovima tražit ću onoga koga ljubi duša moja: tražila sam ga, ali ga nisam našla."},{"v":3,"t":"Sretoše me čuvari koji grad obilaze: “Vidjeste li onoga koga ljubi duša moja?”"},{"v":4,"t":"Tek što pođoh od njih, nađoh onoga koga ljubi duša moja. Uhvatila sam ga i neću ga pustiti, dok ga ne uvedem u kuću majke svoje, u ložnicu roditeljke svoje."},{"v":5,"t":"Zaklinjem vas, kćeri jeruzalemske, srnama i košutama poljskim, ne budite, ne budite ljubav moju dok sama ne bude htjela!"},{"v":6,"t":"Što se to diže iz pustinje kao stup dima iz kada smirne i tamjana i svih prašaka mirodijskih?"},{"v":7,"t":"Gle, to je nosiljka Salomonova, oko nje šezdeset kršnih momaka između najkršnijih u Izraelu."},{"v":8,"t":"Svi su vični mačevima, za rat su izvježbani, svakome je sablja o boku zbog opasnosti noćnih."},{"v":9,"t":"Sebi je prijestolje načinio kralj Salomon od drveta libanskoga."},{"v":10,"t":"Stupove je napravio od srebra, naslon od zlata, sjedište od grimiza, unutra je sve ukrašeno ljubavlju kćeri jeruzalemskih."},{"v":11,"t":"Izađite, kćeri sionske, i vidite kralja Salomona pod dijademom kojim ga mati ovjenčala na dan svadbe njegove, na dan radosti njegova srca."}]},"4":{"hr":[{"v":1,"t":"Kako si lijepa, prijateljice moja, kako si lijepa! Imaš oči kao golubica (kad gledaš) ispod koprene. Kosa ti je kao stado koza što izađoše na brdo Gilead."},{"v":2,"t":"Zubi su ti kao stado ovaca ostriženih kad s kupanja dolaze: idu dvije i dvije kao blizanke i nijedna nije osamljena."},{"v":3,"t":"Usne su tvoje kao trake od grimiza i riječi su tvoje dražesne, kao kriške mogranja tvoji su obrazi pod koprenom tvojom."},{"v":4,"t":"Vrat ti je kao kula Davidova, za obranu sagrađena: tisuću štitova visi na njoj, sve oklopi junački."},{"v":5,"t":"Tvoje su dvije dojke kao dva laneta, blizanca košutina, što pasu među ljiljanima."},{"v":6,"t":"Prije nego dan izdahne i sjene se spuste, poći ću na brdo smirne, na brežuljak tamjana."},{"v":7,"t":"Sva si lijepa, prijateljice moja, i nema mane na tebi."},{"v":8,"t":"Pođi sa mnom s Libana, nevjesto, pođi sa mnom s Libana. Siđi s vrha Amane, s vrha Senira i Hermona, iz lavljih spilja, s planina leopardskih."},{"v":9,"t":"Srce si mi ranila, sestro moja, nevjesto, srce si mi ranila jednim pogledom svojim, jednim samim biserom kolajne svoje."},{"v":10,"t":"Kako je slatka ljubav tvoja, sestro moja, nevjesto! Slađa je ljubav tvoja od vina, a miris ulja tvojih ugodniji od svih mirisa."},{"v":11,"t":"S usana tvojih, nevjesto, saće kapa, pod jezikom ti je med i mlijeko, a miris je haljina tvojih kao miris libanski."},{"v":12,"t":"Ti si vrt zatvoren, sestro moja, nevjesto, vrt zatvoren i zdenac zapečaćen."},{"v":13,"t":"Mladice su tvoje vrt mogranja pun biranih plodova:"},{"v":14,"t":"nard i šafran, mirisna trska i cimet, sa svim stabljikama tamjanovim, smirna i aloj s najboljim mirisima."},{"v":15,"t":"Zdenac je u mom vrtu, izvor žive vode koja teče s Libana."},{"v":16,"t":"Ustani, sjevernjače, duni, južni vjetre, duni nad vrtom mojim, neka poteku njegovi mirisi. Neka dragi moj dođe u vrt svoj, neka jede najbolje plodove u njemu."}]},"5":{"hr":[{"v":1,"t":"Došao sam u vrt svoj, o sestro moja, nevjesto, berem smirnu svoju i balzam svoj, jedem med svoj i saće svoje, pijem vino svoje i mlijeko svoje. Jedite, prijatelji, pijte i opijte se, mili moji!"},{"v":2,"t":"Ja spavam, ali srce moje bdi. Odjednom glas! Dragi moj mi pokuca: “Otvori mi, sestro moja, prijateljice moja, golubice moja, savršena moja, glava mi je puna rose a kosa noćnih kapi.”"},{"v":3,"t":"“Svukla sam odjeću svoju, kako da je odjenem? Noge sam oprala, kako da ih okaljam?”"},{"v":4,"t":"Dragi moj promoli ruku kroz otvor, a sva mi utroba uzdrhta."},{"v":5,"t":"Ustadoh da otvorim dragome svome, a iz ruke mi prokapa smirna i poteče niz prste na ručku zavora."},{"v":6,"t":"Otvorih dragome svome, ali on se već bijaše udaljio i nestao. Ostala sam bez daha kad je otišao. Tražila sam ga, ali ga nisam našla, zvala sam, ali nije se odazvao."},{"v":7,"t":"Sretoše me čuvari koji grad obilaze, tukli su me, ranili i plašt mi uzeli čuvari zidina."},{"v":8,"t":"Zaklinjem vas, kćeri jeruzalemske, ako nađete dragoga moga, što ćete mu reći? Da sam bolna od ljubavi."},{"v":9,"t":"Što je tvoj dragi bolji od drugih, o najljepša među ženama, što je tvoj dragi bolji od drugih te nas toliko zaklinješ?"},{"v":10,"t":"Dragi je moj bijel i rumen, ističe se među tisućama."},{"v":11,"t":"Glava je njegova kao zlato, zlato čisto, uvojci kao palmove mladice, crne poput gavrana."},{"v":12,"t":"Oči su njegove kao golubi nad vodom potočnom; zubi mu kao mlijekom umiveni, u okvir poredani."},{"v":13,"t":"Obrazi su njegovi kao lijehe mirisnog bilja, kao cvijeće ugodno, usne su mu ljiljani iz kojih smirna teče."},{"v":14,"t":"Ruke su mu zlatno prstenje puno dragulja, prsa su njegova kao čista bjelokost pokrita safirima."},{"v":15,"t":"Noge su mu stupovi od mramora na zlatnom podnožju. Stas mu je kao Liban, vitak poput cedra."},{"v":16,"t":"Govor mu je sladak i sav je od ljupkosti. Takav je dragi moj, takav je prijatelj moj, o kćeri jeruzalemske."}]},"6":{"hr":[{"v":1,"t":"Kamo je otišao dragi tvoj, o najljepša među ženama? Kuda je zamakao dragi tvoj, da ga tražimo s tobom?"},{"v":2,"t":"Dragi je moj sišao u svoj vrt k lijehama mirisnog bilja da pase po vrtovima i da bere ljiljane."},{"v":3,"t":"Ja pripadam dragome svome, dragi moj pripada meni, on pase među ljiljanima."},{"v":4,"t":"Lijepa si, prijateljice moja, kao Tirsa, krasna si kao Jeruzalem, strašna kao vojska pod zastavama."},{"v":5,"t":"Odvrati oči svoje od mene jer me zbunjuju. Kosa je tvoja kao stado koza koje silaze s Gileada."},{"v":6,"t":"Zubi su ti kao stado ovaca ostriženih kada s kupanja dolaze: idu dvije i dvije kao blizanke i nijedna nije osamljena."},{"v":7,"t":"Kao kriške mogranja tvoji su obrazi pod koprenom tvojom."},{"v":8,"t":"Ima šezdeset kraljica, osamdeset inoča, a djevojaka ni broja se ne zna."},{"v":9,"t":"Ali je samo jedna golubica moja, savršena moja, jedina u majke, izabrana u roditeljke svoje. Vidjele su je djevojke i nazvale je blaženom, a kraljice i inoče hvale su joj izrekle."},{"v":10,"t":"Tko je ova koja dolazi kao što zora sviće, lijepa kao mjesec, sjajna kao sunce, strašna kao vojska pod zastavama?"},{"v":11,"t":"Siđoh kroz nasade oraha da vidim mladice u dolinama, da pogledam pupaju li vinogradi, cvatu li mogranji."},{"v":12,"t":"Ne znam kako, tek želja moja pope me na kola naroda mog kneževskog."}]},"7":{"hr":[{"v":1,"t":"Vrati se, Sulamko, vrati se, vrati se da te gledamo! Što ćete vidjeti na Sulamki koja pleše u dva zbora?"},{"v":2,"t":"Kako su krasni koraci tvoji u sandalama, kćeri kneževska! Pregibi su bokova tvojih kao grivne stvorene rukom umjetnika."},{"v":3,"t":"Pupak ti je kao okrugla čaša koja nikad nije bez pića. Trbuh ti je kao stog pšenice ograđen ljiljanima."},{"v":4,"t":"Dvije su dojke tvoje dva laneta, blizanca košutina."},{"v":5,"t":"Vrat je tvoj kao kula bjelokosna. Oči su tvoje kao ribnjaci u Hešbonu kod vrata batrabimskih. Nos ti je kao kula libanska što gleda prema Damasku."},{"v":6,"t":"Glava je tvoja kao brdo Karmel, a kosa na glavi kao purpur i kralj se zapleo u njene pletenice."},{"v":7,"t":"Kako si lijepa i kako si ljupka, o najdraža, među milinama!"},{"v":8,"t":"Stas je tvoj kao palma, grudi su tvoje grozdovi."},{"v":9,"t":"Rekoh: popet ću se na palmu da dohvatim vrške njezine, a grudi će tvoje biti kao grozdovi na lozi, miris daha tvoga kao jabuke."},{"v":10,"t":"Usta su tvoja kao najbolje vino. Koje odlazi ravno dragome mome kao što teče na usnama usnulih."},{"v":11,"t":"Ja pripadam dragome svome i on je željan mene."},{"v":12,"t":"Dođi, dragi moj, ići ćemo u polja, noćivat ćemo u selima."},{"v":13,"t":"Jutrom ćemo ići u vinograde da vidimo pupa li loza, zameće li se grožđe, jesu li procvali mogranji. Tamo ću ti dati ljubav svoju."},{"v":14,"t":"Mandragore šire miris, u našim kućama ima svakog voća, novoga i starog, za te sam ga čuvala, o najdraži moj!"}]},"8":{"hr":[{"v":1,"t":"O, da si mi brat, da si sisao prsa majke moje, našla bih te vani, poljubila bih te i nitko me zato ne bi prezirao."},{"v":2,"t":"Povela bih te i uvela u kuću majke svoje koja me odgojila, pojila bih te najboljim vinom i sokom od mogranja."},{"v":3,"t":"Njegova mi je lijeva ruka pod glavom, a desnom me grli."},{"v":4,"t":"Zaklinjem vas, kćeri jeruzalemske, ne budite, ne budite ljubav mojuš dok sama ne bude htjela!"},{"v":5,"t":"Tko je ta što dolazi iz pustinje, naslonjena na dragoga svoga? Probudio sam te pod jabukom gdje te mati rodila, gdje te na svijet dala roditeljka tvoja."},{"v":6,"t":"Stavi me kao znak na srce, kao pečat na ruku svoju, jer ljubav je jaka kao smrt, a ljubomora tvrda kao grob. Žar je njezin žar vatre i plamena Jahvina."},{"v":7,"t":"Mnoge vode ne mogu ugasiti ljubav niti je rijeke potopiti. Da netko daje za ljubav sve što u kući ima, taj bi navukao prezir na sebe."},{"v":8,"t":"Imamo malu sestru koja još nema grudi, što ćemo činiti sa svojom sestrom kad bude riječ o njoj?"},{"v":9,"t":"Ako bude poput zida, sagradit ćemo na njemu krunište od srebra; ako bude poput vrata, utvrdit ćemo ih cedrovim daskama."},{"v":10,"t":"Ja sam zid i grudi su moje kule: tako postadoh u očima njegovim kao ona što nađe smirenje."},{"v":11,"t":"Salomon ima vinograd u Baal Hamonu, dao ga je čuvarima i svaki mora donijeti za urod tisuću srebrnjaka."},{"v":12,"t":"Moj vinograd je preda mnom: tebi, Salomone, tisuća, a dvjesta onima što čuvaju plodove."},{"v":13,"t":"O ti, koja boraviš u vrtovima, drugovi slušaju glas tvoj, daj da ga i ja čujem!"},{"v":14,"t":"Pohitaj, mili moj, budi kao srna i kao jelenče na gorama mirisnim!"}]}},"ISA":{"1":{"hr":[{"v":1,"t":"Viđenje Izaije, sina Amosova, koje je imao o Judeji i Jeruzalemu u dane Uzije, Jotama, Ahaza i Ezekije, kraljeva judejskih."},{"v":2,"t":"Čujte, nebesa, poslušaj, zemljo, jer Jahve govori: “Sinove sam ti odgojio, podigao, al' se oni od mene odvrgoše."},{"v":3,"t":"Vo poznaje svog vlasnika, a magarac jasle gospodareve - Izrael ne poznaje, narod moj ne razumije.”"},{"v":4,"t":"Jao, grešna li naroda, puka u zlu ogrezla, roda zlikovačkog, pokvarenih sinova! Jahvu ostaviše, prezreše Sveca Izraelova, njemu su okrenuli leđa."},{"v":5,"t":"TÓa gdje da vas još udarim, odmetnici tvrdokorni? Sva je glava bolna, srce iznemoglo;"},{"v":6,"t":"od pete do glave nidje zdrava mjesta, već ozljede, modrice, otvorene rane, ni očišćene, ni povijene, ni uljem ublažene."},{"v":7,"t":"Zemlja vam opustje, gradove oganj popali, njive vam na oči haraju tuđinci - pustoš k'o kad propade Sodoma."},{"v":8,"t":"Kći sionska ostade kao koliba u vinogradu, kao pojata u polju krastavaca, kao grad opsjednut."},{"v":9,"t":"Da nam Jahve nad Vojskama ne ostavi Ostatak, bili bismo k'o Sodoma, Gomori slični."},{"v":10,"t":"Čujte riječ Jahvinu, glavari sodomski, poslušaj zakon Boga našega, narode gomorski!"},{"v":11,"t":"“Što će mi mnoštvo žrtava vaših?” - govori Jahve. - “Sit sam ovnujskih paljenica i pretiline gojne teladi. I krv mi se ogadi bikova, janjaca i jaradi."},{"v":12,"t":"Kad mi lice vidjet' dolazite, tko od vas ište da gazite mojim predvorjima?"},{"v":13,"t":"Prestanite mi nositi ništavne prinose, kad mi omrznu. Mlađaka, subote i sazive - ne podnosim zborovanja i opačine."},{"v":14,"t":"Mlađake i svetkovine vaše iz sve duše mrzim - teški su mi, podnijet' ih ne mogu!"},{"v":15,"t":"Kad na molitvu ruke širite, je od vas oči odvraćam. Molitve samo množite, ja vas ne slušam. Ruke su vam u krvi ogrezle,"},{"v":16,"t":"operite se, očistite. Uklonite mi s očiju djela opaka, prestanite zlo činiti!"},{"v":17,"t":"Učite se dobrim djelima: pravdi težite, ugnjetenom pritecite u pomoć, siroti pomozite do pravde, za udovu se zauzmite.”"},{"v":18,"t":"“Hajde, dakle, da se pravdamo,” govori Jahve. “Budu l' vam grijesi kao grimiz, pobijeljet će poput snijega; kao purpur budu li crveni, postat će kao vuna."},{"v":19,"t":"Htjednete l' me poslušati, uživat ćete plodove zemaljske."},{"v":20,"t":"U buntovništvu ako ustrajete, proždrijet će vas mač.” Tako usta Jahvina govorahu."},{"v":21,"t":"Kako li posta bludnicom tvrđa vjerna? Bješe puna pravičnosti, pravda u njoj stolovala, a sad - ubojice."},{"v":22,"t":"Srebro ti se u trosku obratilo, vino ti se razvodnjelo."},{"v":23,"t":"Knezovi se tvoji odmetnuli, s tatima se pobratili. Svi za mitom hlepe, za darovima lete. Siroti pravdu uskraćuju, udovička parnica ne stiže k njima."},{"v":24,"t":"Stog ovako govori Jahve, Gospod nad Vojskama, Junak Izraelov: “Ah, kad se iskalim na protivnicima i osvetim dušmanima!"},{"v":25,"t":"Kada na te ruku pružim, da lužinom tvoju trosku očistim, da iz tebe uklonim olovo!"},{"v":26,"t":"Da ti opet postavim suce kao negda, savjetnike kao u početku, pa da te zovu Gradom pravednim, Tvrđom vjernosti.”"},{"v":27,"t":"Sud pravedni otkupit će Sion, a pravda obraćenike njegove."},{"v":28,"t":"Otpadnici i grešnici skršit će se zajedno, a oni što Jahvu napuštaju poginut će."},{"v":29,"t":"Da, stidjet ćete se zbog hrastova što ih sad obožavate i crvenjet ćete zbog gajeva u kojima sad uživate."},{"v":30,"t":"Jer, bit ćete poput hrasta osušena lišća i poput gaja u kojem vode nema."},{"v":31,"t":"Junak će biti kučina, a iskra djelo njegovo, zajedno će izgorjeti, a nikoga da ugasi."}]},"2":{"hr":[{"v":1,"t":"Viđenje Izaije, sina Amosova, o Judeji i Jeruzalemu:"},{"v":2,"t":"Dogodit će se na kraju dana: Gora Doma Jahvina bit će postavljena vrh svih gora, uzvišena iznad svih bregova. K njoj će se stjecati svi narodi,"},{"v":3,"t":"nagrnut će mnoga plemena i reći: “Hajde, uziđimo na Goru Jahvinu, pođimo u Dom Boga Jakovljeva! On će nas naučiti svojim putovima, hodit ćemo stazama njegovim. Jer će iz Siona Zakon doći, iz Jeruzalema riječ Jahvina.”"},{"v":4,"t":"On će biti sudac narodima, mnogim će sudit' plemenima, koji će mačeve prekovati u plugove, a koplja u srpove. Neće više narod dizat' mača protiv naroda nit' se više učit' ratovanju."},{"v":5,"t":"Hajde, dome Jakovljev, u Jahvinoj hodimo svjetlosti!"},{"v":6,"t":"Da, ti si svoj odbacio narod, dom Jakovljev, jer je pun vračeva s istoka i gatara kao Filistejci, bratime se s tuđincima."},{"v":7,"t":"Zemlja mu je puna srebra i zlata i blagu mu kraja nema; zemlja mu je puna konja, kolima mu broja nema."},{"v":8,"t":"Zemlja mu je prepuna kumira i oni se klanjaju pred djelom ruku svojih, pred onim što njihovi načiniše prsti."},{"v":9,"t":"Smrtnik će se poviti, čovjek sniziti; ne praštaj im."},{"v":10,"t":"Uđi među pećine, skrij se u prašinu, pred užasom Jahvinim, pred sjajem veličanstva njegova, kad ustane da potrese zemlju."},{"v":11,"t":"Ohol pogled bit će skršen i bahatost ljudska ponižena. Jahve će se uzvisiti, on jedini - u dan onaj."},{"v":12,"t":"Da, bit će to dan Jahve nad Vojskama, protiv svih oholih i bahatih, protiv sviju što se uzvisiše, da ih obori;"},{"v":13,"t":"protiv svih cedrova libanonskih i svih hrastova bašanskih;"},{"v":14,"t":"protiv svih gora uznositih i svih bregova uzdignutih;"},{"v":15,"t":"protiv svake visoke tvrđe i svih tvrdih zidina;"},{"v":16,"t":"protiv sveg brodovlja taršiškog i svih brodova raskošnih."},{"v":17,"t":"Oholost ljudska skršit će se i bahatost ljudska poniziti. Jahve će se uzvisiti, on jedini - u dan onaj,"},{"v":18,"t":"i kumiri će netragom nestati."},{"v":19,"t":"Uđite u rupe među pećinama i u spilje zemaljske pred užasom Jahvinim, pred sjajem veličanstva njegova, kad ustane da potrese zemlju."},{"v":20,"t":"U dan onaj: bacit će svaki svoje srebro i zlatne kumire koje sebi načini da im se klanja,"},{"v":21,"t":"kad uteče u šupljine pećina i u raspukline stijena pred užasom Jahvinim, pred sjajem veličanstva njegova, kad ustane da potrese zemlju."},{"v":22,"t":"Čuvajte se, dakle, čovjeka koji ima samo jedan dah u nosnicama: jer što vrijedi?"}]},"3":{"hr":[{"v":1,"t":"Gle, Gospod, Jahve nad Vojskama, oduzima Jeruzalemu i Judeji svaku potporu, pomoć u kruhu i pomoć u vodi,"},{"v":2,"t":"junaka i ratnika, suca i proroka, vrača i starješinu, pedesetnika i odličnika,"},{"v":3,"t":"savjetnika i mudra gatara i onoga što se bavi čaranjem."},{"v":4,"t":"“A za glavare postavljam im djecu, dajem deranima da njima vladaju.”"},{"v":5,"t":"Ljudi se glože jedan s drugim i svaki s bližnjim svojim; dijete nasrće na starca, prostak na odličnika"},{"v":6,"t":"te svatko brata hvata u očinskoj kući: “Ti imaš plašt, budi nam glavarom, uzmi u ruke ovo rasulo!”"},{"v":7,"t":"A on će se, u dan onaj, braniti: “Neću da budem vidar, nema u mene ni kruha ni plašta: ne stavljajte me narodu za glavara.”"},{"v":8,"t":"Jeruzalem se ruši i pada Judeja, jer im se jezik i djela Jahvi protive te prkose pogledu Slave njegove."},{"v":9,"t":"Lice njihovo protiv njih svjedoči, razmeću se grijehom poput Sodome i ne kriju ga, jao njima, sami sebi propast spremaju."},{"v":10,"t":"Kažite: “Blago pravedniku, hranit će se plodom djela svojih!"},{"v":11,"t":"Jao opakome, zlo će mu biti, na nj će pasti djela ruku njegovih.”"},{"v":12,"t":"Deran tlači narod moj i žene njime vladaju. O narode moj, vladaoci te tvoji zavode i raskapaju put kojim hodiš."},{"v":13,"t":"Ustade Jahve da se popravda s narodom svojim,"},{"v":14,"t":"Jahve dolazi na sud sa starješinama i glavarima svog naroda: “Vinograd ste moj opustošili, u vašim je kućama što oteste siromahu."},{"v":15,"t":"S kojim pravom narod moj tlačite i gazite lice siromaha?” - riječ je Jahve, Gospoda nad Vojskama."},{"v":16,"t":"I reče Jahve: “Što se to ohole kćeri sionske te ispružena vrata hode, okolo okom namiguju, koracima sitnim koracaju, grivnama na nozi zveckaju?"},{"v":17,"t":"Oćelavit će Gospod tjeme kćeri sionskih, obnažit će Jahve golotinju njihovu.”"},{"v":18,"t":"U onaj će dan Gospod strgnuti sve čime se ona ponosi: ukosnice i mjesečiće,"},{"v":19,"t":"naušnice, narukvice i koprene,"},{"v":20,"t":"poveze, lančiće, pojaseve, bočice s miomirisima i privjese,"},{"v":21,"t":"prstenje i nosne prstenove,"},{"v":22,"t":"skupocjene haljine i plašteve, prijevjese i torbice,"},{"v":23,"t":"zrcala i košuljice, povezače i rupce."},{"v":24,"t":"Mjesto miomirisa, smrad; mjesto pojasa, konopac; mjesto kovrča, tjeme obrijano; mjesto gizdave halje, kostrijet; mjesto ljepote, žig."},{"v":25,"t":"Muževi tvoji od mača će pasti, junaci tvoji u kreševu."},{"v":26,"t":"Vrata će tvoja kukat' i tugovati, na zemlji ćeš sjedit' napuštena."}]},"4":{"hr":[{"v":1,"t":"I sedam će se žena jagmiti za jednoga čovjeka - u dan onaj: “Svoj ćemo kruh jesti,” reći će, “i u halje se svoje oblačiti, daj nam samo da tvoje nosimo ime, skini sa nas svu sramotu našu.”"},{"v":2,"t":"U onaj će dan izdanak Jahvin biti na diku i na slavu, a plod zemlje na ponos i ures spašenima u Izraelu."},{"v":3,"t":"Koji ostanu na Sionu i prežive u Jeruzalemu, zvat će se “sveti” i bit će upisani da u Jeruzalemu žive."},{"v":4,"t":"Kad Gospod spere ljagu kćeri sionskih i obriše s Jeruzalema krv prolivenu dahom suda i dahom što spaljuje,"},{"v":5,"t":"sazdat će Jahve nad svom Gorom sionskom i nad svima što ondje budu zborovali oblak s dimom danju, a noću sjaj ognja žarkoga. Jer, vrh svega Slava će biti zaklon"},{"v":6,"t":"i sjenica da zasjenjuje danju od pripeke, štit i utočište od pljuska i oluje."}]},"5":{"hr":[{"v":1,"t":"Zapjevat ću svojemu dragome, pjesmu svog ljubljenog njegovu vinogradu. Moj je dragi imao vinograd na brežuljku rodnome."},{"v":2,"t":"Okopa ga, iskrči kamenje, posadi ga lozom plemenitom. Posred njega kulu on podiže i u nj tijesak metnu. Nadaše se da će uroditi grožđem, a on izrodi vinjagu."},{"v":3,"t":"Sad, žitelji jeruzalemski i ljudi Judejci, presudite izmeđ' mene i vinograda mojega."},{"v":4,"t":"Što još mogoh učiniti za svoj vinograd a da nisam učinio? Nadah se da će uroditi grožđem, zašto vinjagu izrodi?"},{"v":5,"t":"No sad ću vam reći što ću učiniti od svog vinograda: plot ću mu soriti da ga opustoše, zidinu razvaliti da ga izgaze."},{"v":6,"t":"U pustoš ću ga obratiti, ni obrezana ni okopana, nek' u drač i trnje sav zaraste; zabranit ću oblacima da dažde nad njime."},{"v":7,"t":"Vinograd Jahve nad Vojskama dom je Izraelov; izabrani nasad njegov ljudi Judejci. Nadao se pravdi, a eto nepravde, nadao se pravičnosti, a eto vapaja."},{"v":8,"t":"Jao vama koji kuću kući primičete i polje s poljem sastavljate, dok sve mjesto ne zauzmete te postanete jedini u zemlji."},{"v":9,"t":"Na uši moje reče Jahve nad Vojskama: “Doista, mnoge će kuće opustjeti, velike i lijepe, bit će bez žitelja."},{"v":10,"t":"Deset rali vinograda dat će samo bačvicu, mjera sjemena dat će samo mjericu.”"},{"v":11,"t":"Jao onima što već jutrom na uranku žestokim se pićem zalijevaju i kasno noću sjede vinom raspaljeni."},{"v":12,"t":"Na gozbama im harfe i citare, bubnjevi i frule uz vino, a za djelo Jahvino ne mare, ne gledaju djelo ruku njegovih."},{"v":13,"t":"Stoga će u ropstvo narod moj odvesti, jer nema razumnosti, odličnici njegovi od gladi će umirati, puk njegov od žeđi će gorjeti."},{"v":14,"t":"Da, Podzemlje će razvaliti ždrijelo, razjapit će ralje neizmjerne da se u njih strmoglave odličnici mu i mnoštvo sa svom grajom i veseljem!"},{"v":15,"t":"Smrtnik će nikom poniknuti, ponizit' se čovjek, oborit će se pogled silnih."},{"v":16,"t":"Jahve nad Vojskama uzvisit će se sudom, i Bog će sveti otkrit' svetost svoju."},{"v":17,"t":"Jaganjci će pasti kao na pašnjacima, a jarci će brstiti po ruševinama bogataškim."},{"v":18,"t":"Jao onima koji na se krivnju vuku volovskom užadi i grijeh kolskim konopcem -"},{"v":19,"t":"onima što govore: “Neka pohiti, neka poteče s djelom svojim da bismo ga vidjeli, neka se približi i završi naum Sveca Izraelova da bismo znali!”"},{"v":20,"t":"Jao onima koji zlo dobrom nazivaju, a dobro zlom, koji od tame svjetlost prave, a od svjetlosti tamu, koji gorko slatkim čine, a slatko gorkim!"},{"v":21,"t":"Jao onima koji su mudri u svojim očima i pametni sami pred sobom!"},{"v":22,"t":"Jao onima koji su jaki u vinu i junaci u miješanju jakih pića;"},{"v":23,"t":"onima koji za mito brane krivca, a pravedniku uskraćuju pravdu!"},{"v":24,"t":"Zato, kao što plameni jezici proždiru slamu i kao što nestaje suha trava u plamenu, tako će korijen njihov istrunuti, poput praha razletjet' se pupoljak njihov, jer odbaciše Zakon Jahve nad Vojskama i prezreše riječ Sveca Izraelova."},{"v":25,"t":"Zato se raspali gnjev Jahvin protiv njegova naroda, i on diže ruku na nj i udari ga te se potresoše gore: trupla njihova leže k'o smeće po ulicama, ali gnjev se njegov još ne smiri, ruka mu je sveđer podignuta."},{"v":26,"t":"On podiže stijeg ratni narodu dalekom, zazviždi mu na kraj zemlje, i gle: brzo, spremno hita."},{"v":27,"t":"U njemu nema trudna ni sustala, ni dremljiva niti snena, oko boka pojas ne otpasuje, na obući ne driješi remena."},{"v":28,"t":"Strijele su mu dobro zašiljene, lukovi mu svi zapeti, kremen su kopita konja njegovih, vihor su točkovi bojnih mu kola."},{"v":29,"t":"Rika mu je k'o u lava i riče k'o lavovi mladi, reži, grabi plijen i odnosi, a nikoga da mu ga istrgne."},{"v":30,"t":"U dan onaj režat će na njega k'o što more buči. Pogledaš li zemlju - sve tmina, tjeskoba, svjetlost proguta tmina oblačna."}]},"6":{"hr":[{"v":1,"t":"One godine kad umrije kralj Uzija, vidjeh Gospoda gdje sjedi na prijestolju visoku i uzvišenu. Skuti njegova plašta ispunjahu Svetište."},{"v":2,"t":"Iznad njega stajahu serafi; svaki je imao po šest krila: dva krila da zakloni lice, dva da zakrije noge, a dvama je krilima letio."},{"v":3,"t":"I klicahu jedan drugome: “Svet! Svet! Svet Jahve nad Vojskama! Puna je sva zemlja Slave njegove!”"},{"v":4,"t":"Od gromka glasa onih koji klicahu stresoše se dovraci na pragovima, a Dom se napuni dimom."},{"v":5,"t":"Rekoh: “Jao meni, propadoh, jer čovjek sam nečistih usana, u narodu nečistih usana prebivam, a oči mi vidješe Kralja, Jahvu nad Vojskama!”"},{"v":6,"t":"Jedan od serafa doletje k meni: u ruci mu žerava koju uze kliještima sa žrtvenika;"},{"v":7,"t":"dotače se njome mojih usta i reče: “Evo, usne je tvoje dotaklo, krivica ti je skinuta i grijeh oprošten.”"},{"v":8,"t":"Tad čuh glas Gospodnji: “Koga da pošaljem? I tko će nam poći?” Ja rekoh: “Evo me, mene pošalji!”"},{"v":9,"t":"On odgovori: “Idi i reci tom narodu: 'Slušajte dobro, al' nećete razumjeti, gledajte dobro, al' nećete spoznati.'"},{"v":10,"t":"Otežaj salom srce tom narodu, ogluši mu uši, zaslijepi oči, da očima ne vidi, da ušima ne čuje i srcem da ne razumije kako bi se obratio i ozdravio.”"},{"v":11,"t":"Ja rekoh: “Dokle, o Gospode?” On mi odgovori: “Dok gradovi ne opuste i ne ostanu bez žitelja, dok kuće ne budu bez ikoga živa, i zemlja ne postane pustoš,"},{"v":12,"t":"dok Jahve daleko ne protjera ljude. Haranje veliko pogodit će zemlju,"},{"v":13,"t":"i ostane li u njoj još desetina, i ona će biti zatrta poput duba kad ga do panja posijeku. Panj će njihov biti sveto sjeme.”"}]},"7":{"hr":[{"v":1,"t":"U dane judejskoga kralja Ahaza, sina Jotamova, sina Uzijina, aramski kralj Rason i izraelski kralj Pekah, sin Remalijin, zavojštiše na Jeruzalem, ali ga ne mogoše zauzeti."},{"v":2,"t":"Tada dojaviše domu Davidovu: “Aramci se utaborili u Efrajimu.” Na tu vijest uzdrhta srce kraljevo i srce svega naroda, kao što u šumi drveće ustrepti od vjetra."},{"v":3,"t":"I Jahve reče Izaiji: “Iziđi pred Ahaza, ti i sin tvoj Šear Jašub, do nakraj vodovoda gornjeg ribnjaka na putu u Valjarevo polje."},{"v":4,"t":"Reci mu: 'Pazi, smiri se, ne boj se, i nek' ti ne premire srce od ovih dvaju ugaraka zadimljenih, od raspaljenog bijesa Rasona aramskog i sina Remalijina,"},{"v":5,"t":"jer Aram, Efrajim i sin Remalijin smisliše tvoju propast.'"},{"v":6,"t":"Pođimo, rekoše, na Judeju, uplašimo je i osvojimo da u njoj zakraljimo sina Tabelova."},{"v":7,"t":"Ovako govori Jahve Gospod: 'To se neće zbiti: toga biti neće!"},{"v":8,"t":"[8a] Damask je glava Aramcima, a Damasku je glava Rason;"},{"v":9,"t":"Samarija je glava Efrajimcima, a Samariji glava je Remalija. [8b]Još šezdeset i pet godina, i Efrajim, razoren, neće više biti narod. [9b] Ako se na me ne oslonite, održat' se nećete!”"},{"v":10,"t":"Jahve opet progovori Ahazu i reče mu:"},{"v":11,"t":"“Zaišti od Jahve, Boga svoga, jedan znak za sebe iz dubine Podzemlja ili gore iz visina.”"},{"v":12,"t":"Ali Ahaz odgovori: “Ne, neću iskati i neću iskušavati Jahvu.”"},{"v":13,"t":"Tada reče Izaija: “Čujte, dome Davidov. Zar vam je malo dodijavati ljudima, pa i Bogu mom dodijavate!"},{"v":14,"t":"Zato, sam će vam Gospodin dati znak: Evo, začet će djevica i roditi sina i nadjenut će mu ime Emanuel!"},{"v":15,"t":"Vrhnjem i medom on će se hraniti dok ne nauči odbacivat' zlo i birati dobro."},{"v":16,"t":"Jer prije nego dječak nauči odbacivat' zlo i birati dobro, opustjet će zemlja, zbog koje strepiš, od dvaju kraljeva."},{"v":17,"t":"Protiv tebe i protiv tvog naroda i protiv kuće oca tvojega dovest će Jahve dane kakvih ne bijaše otkad se Efrajim odvoji od Jude - kralja asirskoga."},{"v":18,"t":"U dan onaj zazviždat će Jahve muhama na ušću egipatskih rijeka i pčelama u zemlji asirskoj"},{"v":19,"t":"da dođu i popadaju po strmim dolovima, po rasjelinama stijena, po svim trnjacima i svim pojilištima."},{"v":20,"t":"U dan onaj Gospod će obrijati britvom najmljenom s onu stranu Eufrata - kraljem asirskim - kosu s glave, dlake s nogu i bradu s obraza."},{"v":21,"t":"U dan onaj svatko će hraniti po kravu i dvije ovce"},{"v":22,"t":"i od obilja mlijeka koje će mu dati hranit će se vrhnjem; vrhnjem i medom hranit će se koji god u zemlji preostanu."},{"v":23,"t":"U dan onaj gdje god bijaše tisuću čokota, vrijednih tisuću srebrnika, izrast će drač i trnje."},{"v":24,"t":"Onamo će polaziti sa strijelom i lukom, jer sva će zemlja u drač i trnje zarasti."},{"v":25,"t":"A po svim gorama gdje se motikom kopalo nitko više neće ići, strašeći se trnja i drača: onuda će goveda pasti i gaziti ovce.”"}]},"8":{"hr":[{"v":1,"t":"Reče Jahve: “Uzmi veliku ploču i napiši na njoj ljudskim pismom: Maher Šalal Haš Baz - Brz grabež - hitar plijen.”"},{"v":2,"t":"Potom uzeh vjerne svjedoke, svećenika Uriju i Zahariju, sina Berekjina."},{"v":3,"t":"Približih se proročici te ona zače i rodi sina. Jahve mi reče: “Nazovi ga Maher Šalal Haš Baz,"},{"v":4,"t":"jer prije no što dijete počne tepati 'tata' i 'mama', nosit će se pred kralja asirskog sve bogatstvo Damaska i plijen Samarije.”"},{"v":5,"t":"I opet mi reče Jahve:"},{"v":6,"t":"“Jer narod ovaj odbacuje mirne tekućice Šiloaha, a dršće pred Rasonom i pred sinom Remalijinim,"},{"v":7,"t":"navest će Gospod na vas vodu Eufrata, silnu i veliku - kralja asirskog i svu slavu njegovu - i ona će izići iz rukava svoga, preliti se preko svih obala;"},{"v":8,"t":"provalit će u Judeju, razlit' se i poplaviti je, popeti se do grla njezina; i krila će svoja raširiti preko cijele tvoje zemlje, o Emanuele.”"},{"v":9,"t":"Udružite se samo, narodi, al' bit ćete smrvljeni! Poslušajte, vi kraljevi daleki, pašite se, bit ćete smrvljeni, pašite se, bit ćete smrvljeni!"},{"v":10,"t":"Kujte naum - bit će uništen, dogovarajte se samo, bit će uzalud, jer s nama je Bog!"},{"v":11,"t":"Jer, ovako mi reče Jahve, kad me rukom uhvatio i opomenuo da ne idem putem kojim narod ovaj ide:"},{"v":12,"t":"“Ne zovite urotom sve što narod ovaj urotom zove; ne bojte se čega se on boji i nemajte straha."},{"v":13,"t":"Jahve nad Vojskama - on jedini nek' vam svet bude; jedino se njega bojte, strah od njega nek' vas prožme."},{"v":14,"t":"On će vam biti zamka i kamen spoticanja i stijena posrtanja za obje kuće Izraelove, zamka i mreža svim Jeruzalemcima."},{"v":15,"t":"Mnogi će od njih posrnuti, pasti, razbiti se, zaplesti se, uhvatiti.”"},{"v":16,"t":"Pohrani ovo svjedočanstvo, zapečati ovu objavu među učenicima svojim:"},{"v":17,"t":"Čekat ću Jahvu koji je lice svoje sakrio od doma Jakovljeva - u njega ja se uzdam."},{"v":18,"t":"Evo, ja i djeca koju mi Jahve dade Izraelu smo znak i znamenje od Jahve nad Vojskama što prebiva na Gori sionskoj."},{"v":19,"t":"Reknu li vam: “Duhove pitajte i vrače koji šapću i mrmljaju” - dakako, narod mora pitati svoje “bogove” i za žive u mrtvih se raspitivati! -"},{"v":20,"t":"Uza Zakon! Uza svjedočanstvo! Tko ne rekne tako, zoru neće dočekati."},{"v":21,"t":"Lutat će zemljom potlačen i gladan, izgladnjela bijes će ga spopasti, proklinjat će svoga kralja i svog Boga. Okrene l' se k nebu,"},{"v":22,"t":"pogleda l' po zemlji, gle, svuda samo mrak i strava, svuda tmina tjeskobna. Ali će se tama raspršiti,"},{"v":23,"t":"jer više neće biti mraka gdje je sad tjeskoba."}]},"9":{"hr":[{"v":1,"t":"Narod koji je u tmini hodio svjetlost vidje veliku; one što mrklu zemlju obitavahu svjetlost jarka obasja."},{"v":2,"t":"Ti si radost umnožio, uvećao veselje, i oni se pred tobom raduju kao što se ljudi raduju žetvi, k'o što kliču kad se dijeli plijen."},{"v":3,"t":"Teški jaram njegov, prečku što mu pleća pritiskaše, šibu njegova goniča slomi kao u dan midjanski."},{"v":4,"t":"Da, sva bojna obuća, svaki plašt krvlju natopljen izgorjet će i bit će ognju hrana."},{"v":5,"t":"Jer, dijete nam se rodilo, sina dobismo; na plećima mu je vlast. Ime mu je: Savjetnik divni, Bog silni, Otac vječni, Knez mironosni."},{"v":6,"t":"Nadaleko vlast će mu se sterat' i miru neće biti kraja nad prijestoljem Davidovim, nad kraljevstvom njegovim: učvrstit će ga i utvrdit u pravu i pravednosti. Od sada i dovijeka učinit će to privržena ljubav Jahve nad Vojskama."},{"v":7,"t":"Gospod posla riječ protiv Jakova i ona pade na Izraela."},{"v":8,"t":"Sazna je sav narod njegov, Efrajim i stanovnici Samarije koji govorahu naduta i ohola srca:"},{"v":9,"t":"“Opeke nam popadaše, gradit ćemo od tesanika; sasjekoše nam divlje smokve, cedre ćemo posaditi.”"},{"v":10,"t":"Al' Jahve podiže na brdo Sion njegove protivnike i podbada neprijatelje njegove:"},{"v":11,"t":"Aram s istoka, Filistejce sa zapada, da svim ustima proždiru Izraela. Na sve to gnjev se njegov neće smiriti, ruka će mu ostat' ispružena."},{"v":12,"t":"Ali se narod nije obratio onom koji ga je b§io, ne tražiše Jahvu nad Vojskama."},{"v":13,"t":"Zato Jahve odsiječe Izraelu glavu i rep, palmu i rogoz u jednom danu."},{"v":14,"t":"Starješina i odličnik - to je glava; prorok, učitelj laži - to je rep."},{"v":15,"t":"Oni što vode narod taj - zavode ga, a koji se vodit' daju - propali su."},{"v":16,"t":"Stog' mu Gospod neće poštedjet' mladića, sirotama njegovim i udovicama smilovat' se neće. Sav je taj narod bezbožan i zao, na sva usta bezumno govori. Na sve to gnjev se njegov neće smiriti, ruka će mu ostat' ispružena."},{"v":17,"t":"Da, bezbožnost se k'o oganj razmahala, drač i trnje proždire, pa upali šumsku guštaru, stupovi se dima podižu."},{"v":18,"t":"Plamti zemlja od gnjeva Jahvina, narod ognju hrana postaje. Nitko ni brata svog ne štedi, [19b] svatko jede meso svog susjeda."},{"v":19,"t":"[19a] Proždire zdesna, i opet je gladan; guta slijeva, i opet sit nije:"},{"v":20,"t":"Manaše Efrajima, Efrajim Manašea, obojica zajedno Judu. Na sve to gnjev se njegov neće smiriti, ruka će mu ostat' ispružena."}]},"10":{"hr":[{"v":1,"t":"Jao onima koji izdaju odredbe nepravedne, koji ispisuju propise tlačiteljske;"},{"v":2,"t":"koji uskraćuju pravdu ubogima i otimlju pravo sirotinji mog naroda, da oplijene udovice, da opljačkaju sirote!"},{"v":3,"t":"Što ćete činiti u dan kazne kad izdaleka propast dođe? Kom ćete se za pomoć uteći, gdje ostaviti blago svoje"},{"v":4,"t":"da se ne morate među roblje pognuti, pasti među poklanima? Na sve to gnjev se njegov neće smiriti, ruka će mu ostat' ispružena."},{"v":5,"t":"Jao Asiru, šibi gnjeva mojega, prutu kojim srdžba moja zamahuje!"},{"v":6,"t":"Na puk ga poslah nevjeran, na narod što me razjari, da ga oplijeni i opljačka, da ga izgazi k'o blato na ulici."},{"v":7,"t":"Ali on nije tako mislio i u srcu nije tako sudio, već u srcu zasnova zator, istrebljenje mnogih naroda."},{"v":8,"t":"Govoraše: “Nisu li svi knezovi moji kraljevi?"},{"v":9,"t":"Nije li Kalno kao Karkemiš? Nije li Hamat kao Arpad, Samarija kao Damask?"},{"v":10,"t":"Kao što mi ruka dosegnu kraljevstva kumira, bogatija kipovima od Jeruzalema i Samarije,"},{"v":11,"t":"kao što učinih sa Samarijom i kumirima njenim, neću li učiniti s Jeruzalemom i s likovima njegovim?”"},{"v":12,"t":"I kad dovrši Gospod sve djelo svoje na gori Sionu i u Jeruzalemu, kaznit će plod ohola srca kralja asirskog i drskost njegovih ponositih očiju."},{"v":13,"t":"Jer reče: “Učinih snagom svoje ruke i mudrošću svojom, jer sam uman; uklonih međe narodima i blaga njihova opljačkah, kao junak oborih one što sjede na prijestoljima."},{"v":14,"t":"Ruka moja kao gnijezda zgrabi bogatstva naroda. Kao što se kÓupe ostavljena jaja, zemlju svu sam pokupio i nikog ne bi krilima da zalepeće, kljun otvori, zapijuče.”"},{"v":15,"t":"Zar se hvali sjekira povrh onog koji njome siječe? Hoće li se oholit' pila povrh onog koji njome pili? K'o da šiba maše onim koji je podiže, il' štap diže onog koji drvo nije;"},{"v":16,"t":"Jahve nad Vojskama poslat će stoga gojaznima njegovim skončanje, slavu će mu ognjem potpaliti, kao što se vatra potpiruje."},{"v":17,"t":"Svjetlost Izraelova bit će poput ognja, Svetac njegov kao plamen koji će zapalit' i proždrijeti drač njegov i trnje njegovo u jednome danu."},{"v":18,"t":"I krasotu njegovih šuma i voćnjaka uništit će od srčike do kore, ona će biti k'o bolesnik što se trne;"},{"v":19,"t":"ostatak stabala šumskih bit će lako izbrojiti - dijete će ih lako popisati."},{"v":20,"t":"U onaj dan: Ostatak Izraelov i preživjeli iz kuće Jakovljeve neće se više oslanjati na onoga koji ih bije, već će se iskreno oslanjati na Jahvu, Sveca Izraelova."},{"v":21,"t":"Ostatak će se vratiti, ostatak Jakovljev Bogu jakome."},{"v":22,"t":"Zaista, o Izraele, sve da naroda tvojega ima kao pijeska u moru, samo će se Ostatak njegov vratiti. Određeno je uništenje, pravda se prelila,"},{"v":23,"t":"Jahve, Gospod nad Vojskama, poharat će, kako odredi, svu zemlju."},{"v":24,"t":"Zato ovako govori Jahve nad Vojskama: “O narode moj što prebivaš na Sionu, ne boj se Asira kad te šibom tuče, kad štap diže na tebe."},{"v":25,"t":"Jer, još malo, vrlo malo, i gnjev moj će prestati, moja će ih jarost uništiti.”"},{"v":26,"t":"Na nj će Jahve nad Vojskama bičem zamahnuti, kao kad udari Midjan na stijeni Orebu, i štap će dići nad more k'o na putu egipatskom."},{"v":27,"t":"U onaj dan: s leđa će ti breme pasti i jaram njegov s vrata će ti nestat'."},{"v":28,"t":"Ide on od Rimona, dolazi na Ajat, prelazi Migron, u Mikmasu breme odlaže."},{"v":29,"t":"Prelaze klance, u Gebi im je noćište; Rama dršće, Gibea Šaulova bježi."},{"v":30,"t":"Viči iza glasa, Bat Galime! Slušaj ga, Lajšo! Odgovori mu, Anatote!"},{"v":31,"t":"Madmena pobježe, utekoše stanovnici gebimski."},{"v":32,"t":"Još danas zaustavit će se u Nobu, rukom prijeti gori Kćeri sionske, Brijegu jeruzalemskom."},{"v":33,"t":"Gle, Jahve, Gospod nad Vojskama, kreše grane silom strahovitom: najviši su vršci posječeni, ponajviši sniženi."},{"v":34,"t":"Pod sjekirom pada šumska guštara, sa slavom svojom pada Libanon."}]},"11":{"hr":[{"v":1,"t":"Isklijat će mladica iz panja Jišajeva, izdanak će izbit' iz njegova korijena."},{"v":2,"t":"Na njemu će duh Jahvin počivat', duh mudrosti i umnosti, duh savjeta i jakosti, duh znanja i straha Gospodnjeg."},{"v":3,"t":"Prodahnut će ga strah Gospodnji: neće suditi po viđenju, presuđivati po čuvenju,"},{"v":4,"t":"već po pravdi će sudit' ubogima i sud prav izricat' bijednima na zemlji. Šibom riječi svoje ošinut će silnika, a dahom iz usta ubit' bezbožnika."},{"v":5,"t":"On će pravdom opasati bedra, a vjernošću bokove."},{"v":6,"t":"Vuk će prebivati s jagnjetom, ris ležati s kozlićem, tele i lavić zajedno će pasti, a djetešce njih će vodit'."},{"v":7,"t":"Krava i medvjedica zajedno će pasti, a mladunčad njihova skupa će ležati, lav će jesti slamu k'o govedo."},{"v":8,"t":"Nad rupom gujinom igrat će se dojenče, sisanče će ruku zavlačiti u leglo zmijinje."},{"v":9,"t":"Zlo se više neće činiti, neće se pustošiti na svoj svetoj gori mojoj: zemlja će se ispuniti spoznajom Jahvinom kao što se vodom pune mora."},{"v":10,"t":"U dan onaj: Jišajev izdanak, dignut kao stijeg narodima, puci će željno tražiti. I prebivalište njegovo bit će slavno."},{"v":11,"t":"U dan onaj: Jahve će drugi put ruku pružiti da otkupi Ostatak svoga naroda, one što ostanu iz Asira i iz Egipta, iz Patrosa, Kuša i Elama, iz Šineara, Hamata i s morskih otoka."},{"v":12,"t":"Podignut će stijeg narodima, sabrat će Izraelu prognanike i skupiti Judi raspršene sa sva četiri kraja zemlje."},{"v":13,"t":"Ljubomor će nestat' Efrajimov, bit će istrijebljeni dušmani Judini; Efrajim neće više zavidjeti Judi, a Juda neće biti neprijatelj Efrajimu."},{"v":14,"t":"Filistejcima na zapadu za vrat će sjesti, zajedno će plijeniti sinove Istoka; ruku će svoju pružit' na Edom i Moab, bit će im pokorni sinovi Amonovi."},{"v":15,"t":"Jahve će isušit' zaljev mora egipatskog, zamahnut će rukom protiv Eufrata; snagom daha razbit će ga na sedam potoka da se u obući može prelaziti:"},{"v":16,"t":"i bit će cesta Ostatku njegova naroda, koji preživio bude iz Asira, kao što bijaše Izraelcima kad iziđoše iz zemlje egipatske."}]},"12":{"hr":[{"v":1,"t":"Reći ćeš u dan onaj: Hvalim te, Jahve, razgnjevi se ti na mene, ali se odvratio gnjev tvoj i ti me utješi!"},{"v":2,"t":"Evo, Bog je spasenje moje, uzdam se, ne bojim se više, jer je Jahve snaga moja i pjesma, on je moje spasenje."},{"v":3,"t":"I s radošću ćete crpsti vodu iz izvora spasenja."},{"v":4,"t":"Reći ćete u dan onaj: Hvalite Jahvu prizivajte ime njegovo! Objavite narodima djela njegova, razglašujte uzvišenost imena njegova!"},{"v":5,"t":"Pjevajte Jahvi, jer stvori divote, neka je to znano po svoj zemlji!"},{"v":6,"t":"Kličite i radujte se, stanovnici Siona, jer je velik među vama Svetac Izraelov!"}]},"13":{"hr":[{"v":1,"t":"Proroštvo o Babilonu koje vidje Izaija, sin Amosov."},{"v":2,"t":"Na goletnu brdu dignite zastavu, vičite im iz sveg grla. Mašite rukom neka dođu na vrata kneževska."},{"v":3,"t":"Zapovijed dadoh svetim svojim ratnicima, gnjevu svom pozvah svoje junake koji slave veličanstvo moje."},{"v":4,"t":"Čuj! Žagor na gorama kao od silna naroda. Čuj! Buka kraljevstava, sakupljenih naroda. To Jahve nad Vojskama za boj vojsku pregleda."},{"v":5,"t":"Iz daleka kraja, s granica neba dolaze oni - Jahve i oruđa gnjeva njegova - da svu zemlju poharaju."},{"v":6,"t":"Kukajte, jer je blizu Jahvin dan, k'o pohara dolazi od Svemoćnog."},{"v":7,"t":"I sve ruke stog' malakšu ... Svako ljudsko srce klone,"},{"v":8,"t":"strava ih je obrvala, trudovi boli već ih spopadaju i grče se k'o rodilja. U prepasti jedan drugog motre, lica su im poput plamena."},{"v":9,"t":"Dolazi nesmiljeni Jahvin dan - gnjev i jarost - da u pustoš zemlju prometne, da istrijebi iz nje grešnike."},{"v":10,"t":"Jer nebeske zvijezde a ni Štapci neće više sjati svjetlošću, pomrčat će sunce ishodeći i mjesec neće više svijetliti."},{"v":11,"t":"Kaznit ću svijet za zloću, bezbožnike za bezakonje, dokrajčit ću ponos oholih, poniziti nadutost silnika."},{"v":12,"t":"Rjeđi će biti čovjek neg' žeženo zlato, rjeđi samrtnik od zlata ofirskog."},{"v":13,"t":"Nebesa ću potresti, maknut će se zemlja s mjesta od srdžbe Jahve nad Vojskama u dan kad se izlije gnjev njegov."},{"v":14,"t":"I tada, kao gazela preplašena, kao ovce koje nitko ne prikuplja, svatko će se vratit' svom narodu, svatko će u zemlju svoju pobjeći."},{"v":15,"t":"Koga stignu, probost će ga: koga uhvate, mačem će sasjeći;"},{"v":16,"t":"pred očima smrskat će im dojenčad, opljačkati kuće, silovati žene."},{"v":17,"t":"Gle, podižem na njih Medijce što ne cijene srebra i preziru zlato."},{"v":18,"t":"Svi će mladići biti pokošeni, sve djevojke zatrte. Na plod utrobe neće se smilovati, nad djecom im se oko neće sažaliti."},{"v":19,"t":"Babilon, ures kraljevstava, ures i ponos kaldejski, bit će k'o Sodoma i Gomora kad ih Bog zatrije."},{"v":20,"t":"Nikad se više neće naseliti, od koljena do koljena ostat će nenapučen. Arapin ondje neće dizati šatora, nit' će pastiri ondje počivati."},{"v":21,"t":"Počivat će ondje zvijeri pustinjske, sove će im napuniti kuće, nojevi će ondje stanovati, jarci plesati."},{"v":22,"t":"Hijene će zavijati iz njegovih palača, a čaglji iz raskošnih dvorova... Vrijeme se njegovo bliži, dani mu se neće produžiti."}]},"14":{"hr":[{"v":1,"t":"Da, smilovat će se Jahve Jakovu i opet izabrati Izraela, dati mu da počine u svojoj zemlji. Pridružit će im se došljak i priključiti se domu Jakovljevu."},{"v":2,"t":"Sami će narodi po njih doći i odvesti ih u njihov kraj, a njih će Dom Izraelov baštiniti u Jahvinoj zemlji kao sluge i sluškinje. I zarobit će one koji njih bijahu zarobili i gospodovat će nad svojim tlačiteljima."},{"v":3,"t":"U dan kad ti Jahve dade da počineš od svojih stradanja, nemira i teškog robovanja kojima te pritisnuše,"},{"v":4,"t":"zapjevat ćeš ovu rugalicu kralju babilonskom: Kako nestade silnika? Kako nestade tlačenja?"},{"v":5,"t":"Jahve slomi štap zlikovački i žezlo vladarsko"},{"v":6,"t":"što je bijesno b§ilo narode udarcima bez kraja i konca, što je gnjevno vladalo narodima progoneć' ih nemilice."},{"v":7,"t":"Počiva, miruje sva zemlja kličući od radosti."},{"v":8,"t":"Nad tobom se raduju čempresi i cedri libanonski: “Otkako si pao, ne dolaze nas više sjeći!”"},{"v":9,"t":"Zbog tebe se uzbudi Podzemlje da te dočeka kada dođeš. U tvoju čast ono budi sjene, sve zemaljske mogućnike, ono diže s prijestolja sve kraljeve naroda."},{"v":10,"t":"Svi ti oni progovaraju: “I ti si skršen k'o i mi, nama si sličan postao."},{"v":11,"t":"Oholost se tvoja sruši u Podzemlje i buka tvojih harfa; pod tobom je ležaj od truleži, a crvi tvoj su pokrivač."},{"v":12,"t":"Kako pade sa nebesa, Svjetlonošo, sine Zorin? Kako li si oboren na zemlju, ti, vladaru naroda?"},{"v":13,"t":"U svom si srcu govorio: 'Uspet ću se na nebesa, povrh zvijezda Božjih prijesto ću sebi dići. Na zbornoj ću stolovati gori na krajnom sjeveru."},{"v":14,"t":"Uzaći ću u visine oblačne, bit ću jednak Višnjemu.'"},{"v":15,"t":"A sruši se u Podzemlje, u dubine provalije!”"},{"v":16,"t":"Koji te vide, motre te i o tebi razmišljaju: “Je li to čovjek koji je zemljom tresao i drmao kraljevstvima,"},{"v":17,"t":"koji je u pustinju svijet obraćao i sa zemljom sravnjivao gradove, koji sužnjeva svojih nikad nije kući otpuštao?”"},{"v":18,"t":"Kraljevi naroda svi u časti počivaju, svaki u svojoj grobnici."},{"v":19,"t":"A ti si iz groba izbačen kao smeće odvratno, pokriven poklanima, mačem probodenima, koji su na ploče grobne pobacani k'o strvina zgažena!"},{"v":20,"t":"Nećeš se združiti s njima u grobu, jer si zemlju svoju uništio i narod svoj poklao. I nikad se više neće spominjati pleme zlikovačko."},{"v":21,"t":"Spremite pokolj djeci za bezakonje otaca njihovih, da se više ne dignu da osvajaju zemlju i da ne pokriju lice svijeta!"},{"v":22,"t":"Ustat ću na njih - riječ je Jahve nad Vojskama - i zatrt ću Babilonu ime i ostatak, rod i porod - riječ je Jahvina."},{"v":23,"t":"Dat ću ga u posjed ježevima i močvarama. Pomest ću ga metlom zatornom - riječ je Jahve nad Vojskama."},{"v":24,"t":"Zakleo se Jahve nad Vojskama: “Što zamislih, zbit će se, što naumih, izvršit će se!"},{"v":25,"t":"Skršit ću Asur u svojoj zemlji, zgazit ću ga na svojim gorama. Jaram njegov s njih će spasti, spast će im s pleća breme njegovo.”"},{"v":26,"t":"Takva je odluka stvorena protiv čitave zemlje; takva je ruka pružena protiv svih naroda!"},{"v":27,"t":"A kad Jahve nad Vojskama odluči, tko da se usprotivi? Kada ruku ispruži, tko da je odvrati?"},{"v":28,"t":"One godine kad je umro kralj Ahaz, bi objavljeno ovo proroštvo:"},{"v":29,"t":"Ne raduj se, sva Filistejo, što se slomi štap koji te udarao, jer će iz korijena zmijinjeg izaći ljutica što će izleći zmaja krilatoga."},{"v":30,"t":"Ubogi će pasti na mojim pašnjacima i u pouzdanju počivati siromasi; glađu ću pomoriti rod tvoj i pobiti što od tebe ostane."},{"v":31,"t":"Kukajte, vrata! Zapomaži, grade! Strepi, sva Filistejo! Jer sa sjevera dim dolazi i čete njegove ne napušta nitko!"},{"v":32,"t":"Što će se tad odgovoriti glasnicima naroda? “Jahve zasnova Sion, i u njem su zaštićeni siromasi njegova naroda.”"}]},"15":{"hr":[{"v":1,"t":"Proroštvo o Moabu. Obnoć opustošen, šaptom pade Ar Moab! Obnoć opustošen, šaptom pade Kir Moab!"},{"v":2,"t":"Uspinju se u hram dibonski, na uzvišice da plaču; nad Nebom i nad Medebom Moab nariče! Sve su glave ostrižene, a sve brade obrijane;"},{"v":3,"t":"na ulicama oblače vreće, na njegovim krovovima leleču! Na njegovim trgovima svi nariču i suze prolijevaju."},{"v":4,"t":"Jauču Hešbon i Eleala, do Jahasa jauk se čuje. Zato dršću bokovi Moabu, strepi duša njegova;"},{"v":5,"t":"srce Moabovo jeca, bjegunci mu idu do Soara. Da, uz brdo Luhit uspinju se plačući; putem horonajimskim razliježe se jauk nad propašću."},{"v":6,"t":"Da! Vode nimrimske postadoše pustinja: trava usahla, bilja nestalo, zelenila više nema."},{"v":7,"t":"Zato stečevinu koju stekoše i ono što prištedješe nose preko Potoka vrba."},{"v":8,"t":"Da! Jauk se razliježe po kraju moapskom: kukanje mu do Eglajima, kukanje mu do Beer Elima."},{"v":9,"t":"Da! Vode dimonske krvi su pune, i još jednu nesreću dodajem Dimonu: jednog lava na moapske bjegunce i na preživjele u zemlji."}]},"16":{"hr":[{"v":1,"t":"Šaljite jaganjce vladaru zemlje, od Stijene prema pustinji do gore Kćeri sionske."},{"v":2,"t":"Kao razbjegle ptice, kao raspršeno gnijezdo bit će kćeri moapske na arnonskim gazovima."},{"v":3,"t":"Daj nam savjet, stvori odluku! Sred podneva sjenu svoju kao noć razastri. Sakrij izagnane, ne izdaj bjegunca."},{"v":4,"t":"Daj da kod tebe borave prognanici moapski, budi im okriljem pred pustošnikom. Kad se skonča tlačitelj, kad nestane pustošnika, kad ugnjetač iščezne iz zemlje,"},{"v":5,"t":"učvrstit će se prijesto u blagosti i na njemu će vjerno stolovati, u šatoru Davidovu, sudac koji pravo ište i pravdu čini."},{"v":6,"t":"Čuli smo za nadutost Moaba, nadutost preveliku, za ponos, oholost i uznositost; isprazno je njegovo hvastanje."},{"v":7,"t":"Zato kuka Moab, nad Moabom svi jauču, za kolačima grožđanim iz Kir Heresa jauču posve slomljeni."},{"v":8,"t":"Jer uvenuše nasadi hešbonski, trsje sibmansko, i lišće su mu pomlatili gospodari naroda. Sezaše do Jazera, zamicaše u pustinju; izdanci mu dosezahu sve do mora."},{"v":9,"t":"Zato plačem za trsjem sibmanskim kao što plače Jazer, suzama te ja zalijevam, Hešbone i Elealo! Nad plodovima tvojim, nad jematvom, krik se začu;"},{"v":10,"t":"nestade iz voćnjaka veselja i radosti. U vinogradima ne pocikuje se, ne kliče se od radosti; ne mastÄi se vino u kaci, zamuknu podvikivanje."},{"v":11,"t":"Zato utroba moja za Moabom poput harfe dršće, a grudi mi za Kir Herešom."},{"v":12,"t":"Zaludu se pokazuje Moab, umara se na uzvišicama dolazeći u svetište da se moli: ništa postići neće."},{"v":13,"t":"Ovo je riječ koju nekoć reče Jahve protiv Moaba."},{"v":14,"t":"A sada govori Jahve ovako: “Za tri godine, godine najamničke, slava će Moabova, sa svim velikim mnoštvom njegovim, potamnjeti, a što od nje ostane, bit će maleno, slabo i nemoćno.”"}]},"17":{"hr":[{"v":1,"t":"Proroštvo o Damasku. Gle, prestat će Damask biti gradom i postat će hrpom ruševina;"},{"v":2,"t":"njegovi gradići, dovijek napušteni, bit će pašnjak stadima; ležat će u njima i nitko ih neće tjerati."},{"v":3,"t":"Izgubit će Efrajim utvrde, a Damask kraljevstvo; ostatku Arama zbit će se što i slavi sinova Izraelovih - riječ je Jahve nad Vojskama."},{"v":4,"t":"U onaj dan smanjit će se slava Jakovljeva, spast će salo tijela njegova."},{"v":5,"t":"Bit će k'o kad žetelac žito hvata, a ruka mu žanje klasje, kao kad se pabirče klasovi u refajimskoj dolini -"},{"v":6,"t":"ostat će samo pabirci; ili kao kad se otresa maslina: dvije-tri uljike sasvim na vrhu, četiri ili pet na granama drveta - riječ je Jahve, Boga Izraelova."},{"v":7,"t":"U onaj dan čovjek će pogledati na svog Stvoritelja i upraviti oči k Svecu Izraelovu."},{"v":8,"t":"Neće više gledati žrtvenika, djela svojih ruku, neće više gledati onoga što njegovi prsti stvoriše: ašere i sunčane stupove."},{"v":9,"t":"U onaj će dan gradovi tvoji biti napušteni, kao što bjehu napušteni hivijski i amorejski kad ih ostaviše pred Izraelcima, i opustjet će,"},{"v":10,"t":"jer si zaboravio Boga svog spasenja i nisi se spomenuo Stijene svoje snage. Stog' i sadiš ljupke biljke i strane presađuješ mladice;"},{"v":11,"t":"u dan kad ih posadiš, one izrastu, a ujutro procvatu tvoje sadnice, al' propada žetva u dan nevolje, u dan boli neizlječive."},{"v":12,"t":"Jao, buka naroda mnogobrojnih; buče kao što buči more; šum naroda koji šume k'o što šumore silne vode."},{"v":13,"t":"Šume narodi kao što silne vode šumore, al' kad On im zaprijeti, bježe daleko, po gorama razvijani kao pljeva na vjetru, k'o prašina u vihoru."},{"v":14,"t":"Navečer eto straha; prije svanuća više ga nema: to je sudba onih koji nas plijene i kob onih što nas pljačkaju."}]},"18":{"hr":[{"v":1,"t":"Jao zemlji krilatih kukaca s one strane rijeka kuških,"},{"v":2,"t":"tebi koja šalješ morem glasnike i vodom u čamcima rogoznim. Idite, brze skoroteče, k narodu stasitu, tamnoputu, k narodu kog se boje odvajkada, narodu žilavu, zavojevaču, čija je zemlja rijekama izbrazdana."},{"v":3,"t":"Svi stanovnici kruga zemaljskoga, i vi, žitelji zemlje, kad se zastava na brdu digne, gledajte; kad rog zatrubi, slušajte."},{"v":4,"t":"Jer ovako mi govori Jahve: “Mirno ću gledati s mjesta svojega, k'o prozirna žega podnevna, k'o rosan oblak za vrućine žetvene."},{"v":5,"t":"Prije berbe, kad loza ocvate i cvijet u grozdove dozri, nožima će posjeći mladice, povezati, ukloniti grane."},{"v":6,"t":"Svi će biti ostavljeni grabljivicama gorskim i zvijerima zemaljskim. Grabljivice će na njima ljetovati, zvijeri zemaljske zimovati.”"},{"v":7,"t":"U ono će vrijeme narod stasit i tamnoputan, narod kojega se boje odvajkada, narod žilav i zavojevački, čija je zemlja izbrazdana rijekama, donositi darove Jahvi nad Vojskama, k mjestu imena Jahve nad Vojskama - na goru Sion."}]},"19":{"hr":[{"v":1,"t":"Proroštvo o Egiptu. Gle, Jahve sjedi na brzu oblaku, u Egipat dolazi. Dršću pred njim idoli egipatski, u njedrima premire srce Egipćana."},{"v":2,"t":"Podbost ću Egipćane protiv Egipćana, i brat će se s bratom svojim boriti, drug s drugom, grad s gradom, a kraljevstvo s kraljevstvom."},{"v":3,"t":"Egiptu se pamet muti, ja sprečavam njegove naume; oni traže idole i vrače, opsjenare i gatare."},{"v":4,"t":"Egipćane ja predajem u ruke gospodaru okrutnu, kralj silovit njima će vladati - riječ je Jahve nad Vojskama."},{"v":5,"t":"Nestat će vode iz mora, presahnut će i presušiti Rijeka,"},{"v":6,"t":"zaudarat će prokopi, spast će rukavci Rijeke egipatske i presušiti. Uvenut će trska i sita,"},{"v":7,"t":"sva zelen pokraj Nila; usahnut će na Nilu svi usjevi, propast će, raspršit' se, iščeznuti."},{"v":8,"t":"Tužit će ribari, kukat će svi što u Nil udicu bacaju; jadikovat će oni što u vodi mrežu razapinju."},{"v":9,"t":"Postidjet će se lanari, grebenari i tkači bijela tkanja."},{"v":10,"t":"Snuždit će se tkalci, rastužiti radnici."},{"v":11,"t":"Pravi su luđaci knezovi soanski, mudri savjetnici faraonovi glupo svjetuju; kako se usuđujete reći faraonu: “Učenik sam mudraca, učenik drevnih kraljeva?”"},{"v":12,"t":"TÓa gdje su tvoji mudraci? Nek' ti dojave i obznane što je Jahve nad Vojskama nakanio s Egiptom."},{"v":13,"t":"Ludi su knezovi taniški, prevareni knezovi memfiški, oni zavode Egipat, glavare njegovih plemena."},{"v":14,"t":"U njih je ulio Jahve duh vrtoglavi te zavode Egipat u svakom mu činu da tetura k'o pijanac kada bljuje."},{"v":15,"t":"U Egiptu više ne može uspjeti ništa od onog što čine glava i rep, palma i sita."},{"v":16,"t":"U onaj će dan Egipćani postati kao žene, drhtat će i strepiti od zamaha ruke Jahve nad Vojskama kojom će zamahnuti na njih."},{"v":17,"t":"Zemlja će Judina biti na užas Egiptu; kad god je se sjeti, strah će ga obuzeti zbog onoga što je Jahve nad Vojskama protiv njega naumio."},{"v":18,"t":"U onaj će se dan u zemlji egipatskoj pet gradova što govore kanaanskim jezikom zakleti Jahvi nad Vojskama; jedan će se od njih zvati Ir Hahres."},{"v":19,"t":"U onaj će dan biti žrtvenik Jahvin usred zemlje egipatske i stup posvećen Jahvi blizu granice njegove."},{"v":20,"t":"To će Jahvi nad Vojskama biti znak i svjedočanstvo u egipatskoj zemlji. Kad zazovu Jahvu protiv tlačitelja, on će im poslati spasitelja i vođu da ih izbavi."},{"v":21,"t":"I objavit će se Jahve Egipćanima, i u onaj će dan Egipćani spoznati Jahvu; služit će mu žrtvama i prinosima, zavjetovat će se i izvršavati zavjete."},{"v":22,"t":"Jahve će teško udariti Egipćane, ali će ih iscijeliti; obratit će se oni Jahvi i on će ih uslišiti i iscijeliti."},{"v":23,"t":"U onaj će dan ići cesta od Egipta do Asirije. Asirci će dolaziti u Egipat, a Egipćani u Asiriju. Egipat i Asirija služit će Jahvi."},{"v":24,"t":"U onaj će dan Izrael, treći s Egiptom i Asirijom, biti blagoslovljen usred zemlje."},{"v":25,"t":"Jahve nad Vojskama blagoslovit će ga: “Nek' je blagoslovljen”, reći će, “moj narod egipatski, djelo mojih ruku Asirija i baština moja Izrael.”"}]},"20":{"hr":[{"v":1,"t":"U godini kad je vrhovni vojskovođa, koga bijaše poslao Sargon, kralj asirski, došao u Ašdod, napao ga i zauzeo,"},{"v":2,"t":"u to vrijeme reče Jahve po Izaiji, sinu Amosovu: “Hajde, skini kostrijet s bokova i obuću izuj s nogu.” On to učini te iđaše gol i bos."},{"v":3,"t":"Tada reče Jahve: “Kao što je sluga moj Izaija tri godine išao gol i bos kao znak i znamenje Egiptu i Kušu,"},{"v":4,"t":"tako će kralj asirski odvesti sužnje iz Egipta i izgnanike iz Kuša, mlade i stare, gole i bose, otkrivenih zadnjica, sramote Egipta."},{"v":5,"t":"Zbunit će se tad i posramiti zbog Kuša, svoje uzdanice, i Egipta, svojega ponosa."},{"v":6,"t":"I reći će u onaj dan stanovnici ovog primorja: 'Eto, to je uzdanica naša kojoj se utjecasmo da nam pomogne i spasi nas od kralja asirskoga. A kako da se mi spasimo?'”"}]},"21":{"hr":[{"v":1,"t":"Proroštvo primorskoj pustinji. Kao što vihori, hujeći nad Negebom, dolaze iz pustinje, kraja strahotna"},{"v":2,"t":"- otkri mi se u strašnom viđenju - tako pljačkaš pljačka, pustošnik pustoši. “Navali, Elame, opsjedni, Medijo! Dokrajčit ću sve jauke.”"},{"v":3,"t":"Zato bedra moja probadaju grčevi; bolovi me spopadaju k'o trudovi porodilju; od smućenosti ogluših, od straha obnevidjeh."},{"v":4,"t":"Srce mi dršće, groza me obuze, sumrak za kojim čeznuh postade mi užas."},{"v":5,"t":"Postavljaju stol, prostiru stolnjak, jede se i pije ... Ustajte, knezovi, mažite štit!"},{"v":6,"t":"Jer Gospod mi ovako reče: “Idi, postavi stražara! Što vidi, nek' javi."},{"v":7,"t":"Vidi li konjanike, jahače udvojene, jahače na magarcima, jahače na devama, neka dobro pazi s pažnjom napetom!”"},{"v":8,"t":"A stražar viknu: “Povazdan, Gospodaru, stojim na stražarnici, čitavu noć na straži prostojim.”"},{"v":9,"t":"I gle, dolaze konjanici, jahači udvojeni. Oni mi viknuše, oni rekoše: “Pade, pade Babilon! Svi kipovi njegovih bogova o zemlju se razbiše.”"},{"v":10,"t":"Omlaćeno žito, čedo gumna moga, što čuh od Jahve nad Vojskama, Boga Izraelova, objavih vam!"},{"v":11,"t":"Proroštvo o Edomu. Viču mi iz Seira: “Stražaru, koje je doba noći? Stražaru, koje je doba noći?”"},{"v":12,"t":"Stražar odgovori: “Dolazi jutro, a zatim opet noć. Hoćete li pitati, pitajte, vratite se, dođite!”"},{"v":13,"t":"Proroštvo o Arapima. U šikarama pustinjskim počivate, dedanske karavane."},{"v":14,"t":"Vodu iznesite pred žedne, stanovnici zemlje temske, iziđite s kruhom pred bjegunca."},{"v":15,"t":"Pred mačevima bježe oni, pred mačem trgnutim, pred lukom zapetim, pred bojem žestokim."},{"v":16,"t":"Da, ovako mi reče Gospod: “Još jedna godina, godina nadničarska, i nestat će sve slave Kedrove."},{"v":17,"t":"A od mnogobrojnih strijelaca među hrabrim sinovima Kedrovim malo će ih ostati.” Tako je govorio Jahve, Bog Izraelov."}]},"22":{"hr":[{"v":1,"t":"Proroštvo o Dolini viđenja: Što ti je da uzlaziš sav na krovove,"},{"v":2,"t":"grade pun vreve, grade bučni, grade razigrani? Pobijeni tvoji ne padoše od mača, nit' u boju poginuše mrtvi tvoji;"},{"v":3,"t":"glavari svi ti zajedno pobjegoše, u ropstvo padoše luka ne napevši. Zasužnjeni su svi tvoji knezovi, zalud umakoše daleko."},{"v":4,"t":"Zato velim: “Ostavite me, zaplakat ću gorko; nemojte me tješiti zbog uništenja naroda moga.”"},{"v":5,"t":"Jer ovo je dan pometnje i rasula od Jahve, Gospoda nad Vojskama. U Dolini viđenja zid se ruši, vapaj za pomoć diže se u goru."},{"v":6,"t":"Elam tobolac uzima, Aram konja jaše, a Kir štit otkriva."},{"v":7,"t":"Krasne doline tvoje pune su bojnih kola, konjanici stižu pred vrata."},{"v":8,"t":"Tako pada Judi zaštita. U onaj dan svrnuo si pogled na oružje u Šumskoj kući."},{"v":9,"t":"Vidjeste da u gradu Davidovu ima mnogo pukotina. Sabraste vodu iz Donjega ribnjaka."},{"v":10,"t":"Prebrojiste kuće jeruzalemske, porušiste kuće da zid učvrstite."},{"v":11,"t":"Između dva zida načiniste spremište za vodu iz starog ribnjaka. Ali se ne obazreste na Tvorca, nit' vidjeste onog što davno sve smisli."},{"v":12,"t":"Gospod, Jahve nad Vojskama, pozivaše vas u dan onaj da plačete i tugujete, da obrijete glave i pripašete kostrijet."},{"v":13,"t":"A gle: radost i veselje, ubijaju goveda i kolju ovce; jedu meso i piju vino: “Jedimo i pijmo, jer sutra nam je mrijeti.”"},{"v":14,"t":"Ali Jahve nad Vojskama objavi mi: “Dok ne umrete, grijeh taj neće vam se oprostiti”, reče Jahve, Gospod nad Vojskama."},{"v":15,"t":"Ovako govori Jahve, Gospod nad Vojskama: “Hajde, idi k onom dvorjaninu, k Šibni, nadstojniku dvora,"},{"v":16,"t":"koji kleše sebi grob na uzvisini i u stijeni sebi prebivalište usijeca: 'Što tu posjeduješ i koga tu imaš da sebi klešeš grobnicu?'"},{"v":17,"t":"Gle, Jahve će te baciti daleko udarcem jednim jedinim, snažno će te uhvatiti,"},{"v":18,"t":"smotat će te u klupko, kao loptu te baciti po zemlji širokoj! Ondje ti ćeš umrijeti, s kolima što ti bijahu na slavu, ti, sramoto dvoru svoga gospodara!”"},{"v":19,"t":"Lišit ću te tvoje službe, otjerat te sa tvog mjesta;"},{"v":20,"t":"i pozvat ću svoga slugu Elijakima, sina Hilkijina."},{"v":21,"t":"Obući ću mu tvoju haljinu, tvojim ću ga pojasom opasat', tvoju ću mu vlast predati u ruke te će biti otac žiteljima jeruzalemskim i kući Judinoj."},{"v":22,"t":"Metnut ću mu na pleća ključ od kuće Davidove: kad otvori, nitko neće zatvoriti, kad zatvori, nitko neće otvoriti."},{"v":23,"t":"Kao klin zabit ću ga na tvrdu mjestu; i postat će prijesto slave domu oca svojega."},{"v":24,"t":"O njega će se vješati sva slava njegova doma očinskog, izdanci i potomstvo, sve malo posuđe, od zdjelica do ćupova."},{"v":25,"t":"U onaj dan - riječ je Jahve nad Vojskama - izvući će se klin zabijen na tvrdu mjestu, slomit će se i pasti. I sav teret što je visio na njemu razbit će se, jer je Jahve govorio."}]},"23":{"hr":[{"v":1,"t":"Proroštvo o Tiru. Kukajte, lađe taršiške, jer vaša je tvrđa razorena! Javljeno im je dok se iz kitimske vraćahu zemlje."},{"v":2,"t":"Umuknite, stanovnici primorja, trgovci sidonski, kojih su glasnici brodili morem po vodi velikoj."},{"v":3,"t":"Sjetva Nila, žetva Rijeke, bijaše njegovo bogatstvo. On bijaše sajmište narodima."},{"v":4,"t":"Stidi se, Sidone, jer more govori: “Ne hvataju me trudovi niti rađam, ne odgajam momaka nit' podižem djevojaka.”"},{"v":5,"t":"Uzdrhtat će Egipćani kad o Tiru vijest čuju."},{"v":6,"t":"Otplovite u Taršiš, kukajte, stanovnici primorja."},{"v":7,"t":"Je li to vaš grad veseli što postoji od davnih davnina i noge ga daleko nosile da se ondje naseli?"},{"v":8,"t":"Tko li je to odlučio protiv Tira okrunjenog, kojeg trgovci bijahu knezovi a prekupci odličnici zemlje?"},{"v":9,"t":"Jahve nad Vojskama odluči tako da osramoti ponosnu slavu, da ponizi sve odličnike zemlje."},{"v":10,"t":"Obrađuj zemlju, kćeri taršiška, tvoje luke više nema!"},{"v":11,"t":"Ruku svoju Gospod diže na more i kraljevstvima zadrma. Zapovjedi Jahve da se razore tvrđave kanaanske."},{"v":12,"t":"Rekao je: “Nećeš više klikovati, okaljana djevice, kćeri sidonska!” Ustani i idi u Kitim; ni ondje nećeš imati mira."},{"v":13,"t":"Evo zemlje kitimske ... podižu se kule opsadne, razaraju utvrde, sve je ruševina."},{"v":14,"t":"Kukajte, brodovi taršiški, razorena je vaša tvrđava!"},{"v":15,"t":"Dogodit će se, u onaj dan, da će Tir biti zaboravljen sedamdeset godina, kao dani jednoga kralja. A poslije sedamdeset godina Tiru će biti kao bludnici iz pjesme:"},{"v":16,"t":"“Uzmi citaru i skići se gradom, bludnice zaboravljena! Sviraj lijepo, pjevaj mnogo, da te se spomenu!”"},{"v":17,"t":"Poslije sedamdeset godina pohodit će Jahve Tir. I grad će opet dobivati svoju plaću bludničku. Podavat će se bludu sa svim kraljevstvima svijeta na licu zemlje."},{"v":18,"t":"Ali će njegova dobit i plaća biti posvećena Jahvi; neće se zgrtati ni čuvati, nego će njegova dobit biti za one koji prebivaju pred Jahvom da imaju hrane do sita i doličnu odjeću."}]},"24":{"hr":[{"v":1,"t":"Gle, Jahve razvaljuje zemlju, razara je, nakazi joj lice, raspršuje stanovnike njene."},{"v":2,"t":"Svećenik će biti k'o i narod, gospodar k'o i sluga, gospodarica k'o i sluškinja, prodavač k'o i kupac, zajmodavac k'o i zajmoprimac, vjerovnik k'o i dužnik."},{"v":3,"t":"Opustošena će biti zemlja, opljačkana sasvim, jer je Jahve odlučio."},{"v":4,"t":"Zemlja tuži, vene, svijet gine, gasne, nebo sa zemljom propada."},{"v":5,"t":"Oskvrnjena je zemlja pod žiteljima svojim, jer prestupiše Zakon, pogaziše odredbu, Savez vječni razvrgoše."},{"v":6,"t":"Zato prokletstvo proždire zemlju, okajavaju stanovnici njeni. Zato su sažgani žitelji zemljini i malo je ljudi preostalo."},{"v":7,"t":"Vino tuguje, loza vene, uzdišu svi što bijahu srca vesela."},{"v":8,"t":"Prestalo je veselje uz bubnje, zamrla je graja razigrana; umukla je glazba citara."},{"v":9,"t":"Ne pije se više vino uz pjesmu, ogrknu piće silovito."},{"v":10,"t":"Razoren je grad ništavila, zatvoren ulaz svim kućama."},{"v":11,"t":"Jauk po ulicama zbog vina, nesta svakog veselja, radost je iz zemlje prognana."},{"v":12,"t":"Tek pustoš ostade u gradu, u trijeske smrskana su vrata."},{"v":13,"t":"Jer tako se zbiva na zemlji, među narodima, kao kad se oberu masline il' paljetkuje grožđe nakon berbe."},{"v":14,"t":"Oni glas podižu, kliču od radosti; uznose s mora veličajnost Jahvinu."},{"v":15,"t":"I na istoku ime Jahve slave oni, na otocima mora ime Jahve, Boga Izraelova."},{"v":16,"t":"S kraja zemlje čujemo pjesme: “Slava Pravedniku!” Ali ja kažem: “Propadoh! Propadoh! Jao meni! Vjerolomci se iznevjeriše, nevjerom se, vjerolomci, iznevjeriše.”"},{"v":17,"t":"Strava, jama, zamka tebi, žitelju zemlje:"},{"v":18,"t":"tko pred glasom strave uteče u jamu će upasti; tko se iz jame izvuče zamka će ga uhvatit'. Da, otvorit će se ustave u visini i zatresti zemlji temelji."},{"v":19,"t":"Zemlja će se grozno razbiti, zemlja će se strašno raspući, zemlja će se silno uzdrmati,"},{"v":20,"t":"zemlja će zateturati poput pijanca, zanjihat se poput kolibe; toliko će joj otežati bezakonje njeno da će pasti i neće više ustati."},{"v":21,"t":"I dogodit će se u onaj dan: Jahve će kazniti u visini Vojsku nebesku, a na zemlji sve kraljeve zemaljske;"},{"v":22,"t":"bit će sakupljeni i zasužnjeni u jami, zatvoreni u tamnicu i nakon mnogih dana kažnjeni."},{"v":23,"t":"Pocrvenjet će mjesec, postidjet se sunce, jer će kraljevati Jahve nad Vojskama na gori Sionu i u Jeruzalemu i Slava će mu sjati pred starješinama."}]},"25":{"hr":[{"v":1,"t":"Jahve, ti si Bog moj, uznosim te, tvoje ime slavim, jer si proveo čudesan naum, smišljen od davnine, istinit i vjeran,"},{"v":2,"t":"jer grad si pretvorio u hrpu kamenja, a mjesto utvrđeno u ruševine. Tvrđa neprijateljska više nije grad, dovijeka se više obnoviti neće."},{"v":3,"t":"Zato te slavi narod snažan, grad moćnih plemena tebe se boji;"},{"v":4,"t":"jer ti si utočište nevoljnom, utočište ubogom u nevolji; ti si skrovište od pljuska i od žege zaklon, jer ćud je silnička kao pljusak zimski;"},{"v":5,"t":"kao žega nad zemljom sušnom ti gušiš graju neprijatelja; kao žega sjenom oblaka prekinu se silniku pjesma pobjednička."},{"v":6,"t":"I Jahve nad Vojskama spremit će svim narodima na ovoj gori gozbu od pretiline, gozbu od izvrsna vina, od pretiline sočne, od vina staložena."},{"v":7,"t":"Na ovoj gori on će raskinuti zastor što zastiraše sve narode, pokrivač koji sva plemena pokrivaše"},{"v":8,"t":"i uništit će smrt zasvagda. I suzu će sa svakog lica Jahve, Gospod, otrti - sramotu će svog naroda na svoj zemlji skinuti: tako Jahve reče."},{"v":9,"t":"I reći će se u onaj dan: “Gle, ovo je Bog naš, u njega se uzdasmo, on nas je spasio; ovo je Jahve u koga se uzdasmo! Kličimo i veselimo se spasenju njegovu,"},{"v":10,"t":"jer ruka Jahvina na ovoj gori počiva!” Moab je izgažen na svome mjestu kao što se gazi slama na buništu;"},{"v":11,"t":"ondje on razmahuje rukama kao što ih razmahuje plivač kada pliva. Ali Jahve obara njegovu ponositost i propinjanja ruku njegovih."},{"v":12,"t":"Visoku tvrđu tvojih zidina on razvaljuje, na zemlju baca, u prah ruši."}]},"26":{"hr":[{"v":1,"t":"U onaj dan pjevat ću ovu pjesmu u zemlji Judinoj: “Tvrd grad mi imamo: za obranu nam On podiže zidove i predziđa."},{"v":2,"t":"Otvorite vrata! Nek' uđe narod pravedni koji čuva vjernost,"},{"v":3,"t":"čiji je značaj čvrst, koji čuva mir jer se u te uzda."},{"v":4,"t":"Uzdajte se u Jahvu dovijeka, jer Jahve je Stijena vječna;"},{"v":5,"t":"on obara one koji obitavahu visoko, razvaljuje tvrđu visoku, ruši u prah, sravnjuje sa zemljom,"},{"v":6,"t":"te je gaze noge, noge ubogih i koraci nevoljnih.”"},{"v":7,"t":"Put je pravednikov prav, ti ravniš stazu pravednom."},{"v":8,"t":"Da, na stazi tvojih sudova željno te, Jahve, čekamo; ime tvoje i spomen tvoj duša nam žudi."},{"v":9,"t":"Dušom svojom žudim tebe noću i duhom svojim u sebi te tražim. Jer kad se na zemlji pojave tvoji sudovi, uče se pravdi stanovnici kruga zemaljskoga."},{"v":10,"t":"Ako se pomiluje opaki, on se ne uči pravednosti. U zemlji pravednosti on čini bezakonje i ne obazire se na veličanstvo Jahvino."},{"v":11,"t":"Jahve, ruka je tvoja podignuta, a oni je ne vide. Nek' vide i postide se, nek' ih proguta revnost za narod, nek' ih proždre oganj pripravljen dušmanima tvojim."},{"v":12,"t":"Jahve, ti mir nama daješ, jer ti si tvorac svih djela naših."},{"v":13,"t":"Jahve, Bože naš, gospodarili su nama osim tebe drugi gospodari, ali tebe jedinog, ime tvoje, častimo."},{"v":14,"t":"Mrtvi neće oživjeti, sjene neće uskrsnuti, jer ti si ih kaznio i uništio i zatro svaki spomen na njih!"},{"v":15,"t":"Umnožio si narod, Jahve, umnožio si narod, proslavio se, proširio sve granice zemlje!"},{"v":16,"t":"Jahve, tražili su te u nevolji; izlijevali tihu molitvu, kad ih je stigla tvoja kazna."},{"v":17,"t":"Kao što se trudna žena pred porođajem grči i viče u bolovima, takvi smo, Jahve, pred tobom."},{"v":18,"t":"Zatrudnjeli smo, u mukama smo kao da rađamo, nismo donijeli duha spasenja zemlji nit' se rodiše stanovnici svijeta."},{"v":19,"t":"Tvoji će mrtvi oživjeti, uskrsnut će tijela. Probudite se i kličite, stanovnici praha! Jer rosa je tvoja - rosa svjetlosti, i zemlja će sjene na svijet dati."},{"v":20,"t":"Hajde, narode moj, uđi u sobe i vrata za sobom zatvori. Sakrij se časkom dok jarost ne prođe."},{"v":21,"t":"Jer, gle, izići će Jahve iz svog prebivališta da stanovnike zemljine kazni što se o njeg' ogriješiše. Izbacit će zemlja svu krv što je na njoj prolivena i neće više kriti onih koji su na njoj poklani."}]},"27":{"hr":[{"v":1,"t":"U onaj dan kaznit će Jahve mačem ljutim, velikim i jakim Levijatana, zmiju hitru, Levijatana, zmiju vijugavu, i ubit će zmaja morskoga."},{"v":2,"t":"U onaj dan pjevajte mu, vinogradu vinorodnom:"},{"v":3,"t":"Ja, Jahve, njega čuvam, svaki čas ga zalijevam, i da ga tko ne ošteti, danju i noću stražim."},{"v":4,"t":"Nema gnjeva u meni! Nek' se trnje i drač samo pojavi, protiv njega ustat ću u boj, svega ću ga sažgati!"},{"v":5,"t":"Ili u moje nek' dođe okrilje, neka sklopi mir sa mnom, mir neka sklopi sa mnom!"},{"v":6,"t":"Dolaze dani kad će se ukorijeniti Jakov, razgranit' se i procvasti Izrael, i sav svijet plodovima napuniti."},{"v":7,"t":"Je li ga udario kako udari one koji njega udarahu? Je li ga ubio kako ubi one koji njega ubiše?"},{"v":8,"t":"Za kaznu ga potjera, izagna, odnese ga silnim dahom svojim u dan istočnjaka."},{"v":9,"t":"Tako će se okajati bezakonje Jakovljevo; a ovo je sve plod oproštenja grijeha njegova. Neka se smrve svi kamenovi žrtvenika kao što se u prah drobi krečno kamenje! Nek' se više ne dižu ašere i sunčani stupovi!"},{"v":10,"t":"Jer opustje tvrdi grad, naselje je poharano, napušteno kao pustinja. Telad ondje pase - leži ondje, grmlje brsti."},{"v":11,"t":"Kad mu se osuše grane, lome ih, dolaze žene i oganj pale. Jer to je narod nerazuman, zato ga neće žaliti Stvoritelj, Tvorac mu se neće smilovati."},{"v":12,"t":"Jahve će u dan onaj klasje vrijeći od Eufrata do Potoka egipatskog, i bit ćete pobrani jedan po jedan, djeco Izraelova."},{"v":13,"t":"U onaj dan zatrubit će velika trublja, i doći će izgubljeni u zemlji asirskoj, i koji bijahu izgnani u zemlju egipatsku, i poklonit će se Jahvi na Svetoj gori, u Jeruzalemu."}]},"28":{"hr":[{"v":1,"t":"Teško gizdavu vijencu pijanica Efrajimovih, uvelu cvijetu blistava mu nakita - onima što uvrh plodnog dola leže vinom opijeni!"},{"v":2,"t":"Evo, od Gospoda jaki i moćni, kao pljusak s tučom, kao vihor razorni, prolom oblaka i povodanj, i svom ih snagom na zemlju baca."},{"v":3,"t":"Bit će izgažen nogama gizdav vijenac pijanica Efrajimovih"},{"v":4,"t":"i uveo cvijet blistava mu nakita uvrh plodnih dolina; bit će kao rana smokva prije ljeta: čim je tko spazi, odmah je ubere."},{"v":5,"t":"U onaj dan Jahve nad Vojskama postat će kruna slave i sjajan vijenac Ostatku svoga naroda -"},{"v":6,"t":"duh pravde onome koji sjedi na stolici sudačkoj i srčanost onome koji odbija napad na vrata."},{"v":7,"t":"Oni posrću od vina, teturaju od žestoka pića: svećenici i proroci od žestoka pića posrću; omami ih vino; teturaju od žestoka pića, posrću u viđenjima, ljuljaju se sudeći."},{"v":8,"t":"Svi su stolovi puni gnusnih bljuvotina, nigdje čista mjesta nema!"},{"v":9,"t":"“Koga on to uči mudrosti, koga on upućuje u objavu? Zar djecu odviknutu od mlijeka odbijenu od prsiju?"},{"v":10,"t":"Sav la-sav, sav la-sav, kav la-kav, kav la-kav, zeer šam, zeer šam.”"},{"v":11,"t":"Da, mucavim usnama i na stranom jeziku govorit će se ovom narodu."},{"v":12,"t":"On im reče: “Evo počinka, dajte umornom da otpočine! Evo odmora!” Ali ne htjedoše poslušati."},{"v":13,"t":"Zato će im Jahve ovako govoriti: “Sav la-sav, sav la-sav, kav la-kav, kav la-kav, zeer šam, zeer šam”, da hodeći padnu nauznak, da se razbiju, zapletu i uhvate."},{"v":14,"t":"Stoga čujte riječ Jahvinu, vi podsmjevači, vi što vladate narodom ovim koji je u Jeruzalemu."},{"v":15,"t":"Vi velite: “Sklopismo savez sa smrću i s Podzemljem učinismo sporazum. Kad prođe bič razorni, ne, neće nas dohvatiti, jer od laži načinismo sebi sklonište i od obmane skrovište.”"},{"v":16,"t":"Stog ovako govori Jahve Gospod: “Evo, postavljam na Sion kamen odabrani, dragocjen kamen ugaoni, temeljac. Onaj koji u nj vjeruje neće propasti."},{"v":17,"t":"I uzet ću pravo za mjeru, a pravdu za tezulju.” I tuča će vam zastrti sklonište od laži, a voda otplaviti skrovište;"},{"v":18,"t":"propast će savez vaš sa smrću, vaš sporazum s Podzemljem održat' se neće. Kada bič razorni prođe, satrt će vas;"},{"v":19,"t":"kad god prođe, dohvatit će vas; prolazit će svako jutro, danju i noću. Samo će vas strah uputit u objavu."},{"v":20,"t":"Prekratka će bit' postelja da se čovjek pruži, preuzak pokrivač da se umota."},{"v":21,"t":"Da, kao na gori Perasimu, Jahve će ustati, kao u Dolini gibeonskoj, on će se razjariti, da izvrši djelo svoje, djelo čudnovato, da ispuni naum svoj, naum tajnoviti."},{"v":22,"t":"Podsmijevanja se okanite, da vas jače okovi ne stegnu; jer čuh da je od Gospoda, Jahve nad Vojskama, zemlji ovoj dosuđeno uništenje."},{"v":23,"t":"Poslušajte i čujte glas moj, prisluhnite pomno moju besjedu."},{"v":24,"t":"Ore li orač svakog dana, brazdi, brana njivu svoju?"},{"v":25,"t":"A kad joj poravna površinu, ne sije li grahor, ne sipa li kumin? Pšenicu gdje treba, proso i ječam, i napokon raž po rubovima?"},{"v":26,"t":"Bog ga njegov upućuje, on ga uči djelu pravom."},{"v":27,"t":"Ne mlati se grahor cijepom, nećeš točkom po kuminu, već se grahor štapom mlati, a kumin se prutom lupa."},{"v":28,"t":"A da li se žito tare? Ne, nećeš ga dovijeka mlatiti: po njem ćeš pognat kolski točak i konje, ali ga zdrobiti nećeš."},{"v":29,"t":"I to dolazi od Jahve nad Vojskama, savjetom divnog, mudrošću velikog."}]},"29":{"hr":[{"v":1,"t":"Teško Arielu! Arielu, gradu što ga opkoli David! Nek' se niže godina na godinu, nek' se izredaju blagdani,"},{"v":2,"t":"pa ću pritisnuti Ariel i nastat će jauk i lelek. Za mene ćeš biti Ariel,"},{"v":3,"t":"opkolit ću te kao David, rovovima okružiti, suprot tebi nasipe ću dići."},{"v":4,"t":"Oboren govorit ćeš sa zemlje, iz praha mucat' riječju prigušenom, glas će ti se iz zemlje dizat' kao pokojnikov, iz praha ćeš šaptati besjedu."},{"v":5,"t":"Kao sitna prašina bit će mnoštvo tvojih dušmana, kao pljeva razvijana - rulja silnika: i odjednom, u tren oka:"},{"v":6,"t":"pohodit će te Jahve nad Vojskama grmljavinom, tutnjem, bukom velikom, vihorom, olujom i plamenim ognjem što proždire."},{"v":7,"t":"Bit će k'o san, utvara noćna: mnoštvo svih naroda što vojuje s Arielom i svih onih koji zavojštiše na nj i na utvrde njegove i koji ga odasvud pritijesniše."},{"v":8,"t":"Bit će kao kad gladan sanja da jede, a probudi se prazna želuca; i kao kad žedan sanja da pije, pa se, iznemogao, suha grla probudi. Tako će se dogoditi mnoštvu naroda koji vojuju protiv Gore sionske."},{"v":9,"t":"Stanite, skamenite se od čuda, oslijepite i obnevidite! Pijani su, ali ne od vina, posrću, ali ne od silna pića."},{"v":10,"t":"Jahve je izlio na vas duh obamrlosti, zatvorio je oči vaše - proroke, zastro glave vaše - vidioce."},{"v":11,"t":"Zato će vam svako viđenje biti kao riječi u zapečaćenoj knjizi: dade li se kome tko zna čitati govoreći: “De, čitaj to!” - on će odgovoriti: “Ne mogu jer je zapečaćena.”"},{"v":12,"t":"A dade li se kome tko ne zna čitati govoreći: “Čitaj to!” - on će odvratiti: “Ne znam čitati.”"},{"v":13,"t":"Jahve reče: “Jer mi narod ovaj samo ustima pristupa i samo me usnama časti, a srce mu je daleko od mene i njegovo štovanje naučena ljudska uredba,"},{"v":14,"t":"zato ću, evo, i dalje čudno postupati s ovim narodom - čudno i prečudno: i propast će mudrost njegovih mudraca, pomračit se umnost njegovih umnika.”"},{"v":15,"t":"Teško onima koji se od Jahve kriju da bi svoje sakrili namjere i koji u mraku djeluju i zbore: “Tko nas vidi i tko nas pozna?”"},{"v":16,"t":"Kolike li naopakosti vaše! Cijeni li se glina kao lončar, pa da djelo rekne svome tvorcu: “NIje me on načinio”? Ili lonac da rekne lončaru: “On ne razumije ništa”?"},{"v":17,"t":"Neće li se naskoro Libanon u voćnjak pretvoriti, a voćnjak izroditi u šumu?"},{"v":18,"t":"I čut će u onaj dan gluhi riječi knjige; oslobođene mraka i tmine, oči će slijepih vidjeti."},{"v":19,"t":"A siromasi će se opet radovati u Jahvi, najbjedniji će klicat' Svecu Izraelovu,"},{"v":20,"t":"jer neće više biti silnika, nestat će podsmjevača, istrijebit će se svi koji zlo snuju:"},{"v":21,"t":"oni koji riječju druge okrivljuju, oni koji na vratima sucu postavljaju zamku i nizašto obaraju pravednika."},{"v":22,"t":"Zato ovako govori Jahve, Bog kuće Jakovljeve, koji otkupi Abrahama: “Neće se odsad više stidjeti Jakov i više mu neće lice blijedjeti,"},{"v":23,"t":"jer kad vidi usred sebe djelo mojih ruku, svetit će ime moje.” Svetit će Sveca Jakovljeva, bojat će se Boga Izraelova."},{"v":24,"t":"Zabludjeli duhom urazumit će se, a oni što mrmljaju primit će pouku."}]},"30":{"hr":[{"v":1,"t":"Teško sinovima odmetničkim! - riječ je Jahvina. Oni provode osnove koje nisu moje, sklapaju saveze koji nisu po mom duhu i grijeh na grijeh gomilaju."},{"v":2,"t":"Zaputiše se u Egipat, ne pitajući usta moja, da se uteku faraonovu zaklonu i da se zaštite u sjeni Egipta."},{"v":3,"t":"Zaklon faraonov bit će na sramotu, i na ruglo zaštita u sjeni Egipta."},{"v":4,"t":"Eno mu knezova već u Soanu, podanici stigoše u Hanes:"},{"v":5,"t":"svi će se oni razočarati u narodu beskorisnom, neće im biti na pomoć ni na korist, već na sramotu i porugu."},{"v":6,"t":"Proroštvo o negepskim životinjama. Kroza zemlju nevolje i bijede, lavice i lava koji riču, ljutice i zmaja krilatog, nose oni blago na leđima magaraca i bogatstvo na grbi deva, nose ga narodu beskorisnom."},{"v":7,"t":"Jer prazna je i ništavna pomoć Egipta, zato ga i zovemo: Rahab - danguba."},{"v":8,"t":"Ded napiši na ploču i zapiši u knjigu da vremenima budućim svjedočanstvo ostane."},{"v":9,"t":"Ovo je narod odmetnički, sinovi lažljivi, sinovi koji neće da slušaju Zakon Jahvin."},{"v":10,"t":"Vidovitima oni govore: “Okanite se viđenja!” a vidiocima: “Ne prorokujte istinu! Govorite nam što je ugodno, opsjene nam prorokujte!"},{"v":11,"t":"Skrenite s puta, zastranite sa staze, uklonite nam s očiju Sveca Izraelova!”"},{"v":12,"t":"Stog' ovako zbori Svetac Izraelov: “Jer riječ ovu odbacujete, a uzdate se u opačinu i prijevaru i na njih se oslanjate,"},{"v":13,"t":"grijeh će vam taj biti poput pukotine, visoko na zidu izbočene, koja prijeti rušenjem."},{"v":14,"t":"Da se sruši k'o što se glinen sud razbije, slupan nemilice, te mu se među krhotinama ne nađe ni rbine, žerave da uzmeš s ognjišta il' zagrabiš vode iz studenca.”"},{"v":15,"t":"Jer ovako govori Jahve Gospod, Svetac Izraelov: “Mir i obraćenje - spas vam je, u smirenu uzdanju snaga je vaša. Ali vi ne htjedoste."},{"v":16,"t":"Rekoste: 'Ne! Pobjeći ćemo na konjima!' - i zato, bježat ćete! 'Na brzim ćemo konjima jahati!' - i zato, bit će brži vaši neprijatelji!”"},{"v":17,"t":"Pobjeći će vas tisuća kad jedan zaprijeti, zaprijete li petorica, u bijeg ćete nagnut' dok vas ne preostane k'o kopljača na vrhu gore il' na brijegu zastava."},{"v":18,"t":"Al' Jahve čeka čas da vam se smiluje, i stog izglÄedÄa da vam milost iskaže, jer Jahve je Bog pravedan - blago svima koji njega čekaju."},{"v":19,"t":"Da, puče sionski koji živiš u Jeruzalemu, više ne plači! Čim začuje vapaj tvoj, odmah će ti se smilovati; čim te čuje, uslišit će te."},{"v":20,"t":"Hranit će vas Gospod kruhom tjeskobe, pojiti vodom nevolje, al' se više neće kriti tvoj Učitelj - oči će ti gledati Učitelja tvoga."},{"v":21,"t":"I uši će tvoje čuti riječ gdje iza tebe govori: “To je put, njime idite”, bilo da vam je krenuti nadesno ili nalijevo."},{"v":22,"t":"Smatrat ćeš nečistima svoje srebrne kumire i pozlatu svojih kipova; odbacit ćeš ih kao nečist i reći im: “Napolje!”"},{"v":23,"t":"A on će dati kišu tvojem sjemenu što ga posiješ u zemlju, i kruh kojim zemlja urodi bit će obilat i hranjiv. Stoka će tvoja pasti u onaj dan po prostranim pašnjacima."},{"v":24,"t":"Volovi i magarci što obrađuju zemlju jest će osoljenu krmu, ovijanu lopatom i vijačom."},{"v":25,"t":"I na svakoj gori i na svakome povišenom brijegu bit će potoka i rječica - u dan silnoga pokolja kad se kule budu rušile."},{"v":26,"t":"Tada će svjetlost mjesečeva biti kao svjetlost sunčana, a svjetlost će sunčana postati sedam puta jača, kao svjetlost sedam dana - u dan kad Jahve iscijeli prijelom svojemu narodu, izliječi rane svojih udaraca."},{"v":27,"t":"Gle, ime Jahve izdaleka dolazi, gnjev njegov gori, dim je neizdrživ. Usne su mu pune jarosti, jezik mu oganj što proždire."},{"v":28,"t":"Dah mu je kao potok nabujali što do grla seže. On dolazi da prosije narode rešetom zatornim, da stavi uzde zavodljive u čeljusti naroda."},{"v":29,"t":"Tad će vam pjesma biti kao u noćima blagdanskim, kad su srca vesela kao u onoga koji uza zvuke frule hodočasti na Goru Jahvinu, k Stijeni Izraelovoj."},{"v":30,"t":"Jahve će zagrmjet glasom veličajnim i pokazat ruku svoju što udara u jarosnu gnjevu, sred ognja zatornog, iz olujna pljuska i krupÄe kamene."},{"v":31,"t":"Od glasa Jahvina prepast će se Asur, šibom ošinut."},{"v":32,"t":"I kad god ga udari šiba kaznena, kojom će ga Jahve išibati, nek' se oglase bubnjevi i citare - u sav jek boja on s njima ratuje!"},{"v":33,"t":"Odavna je pripravljen Tofet za Moleka - lomača visoka, široka, mnogo ognja, mnogo drvlja. Dah gnjeva Jahvina, kao potok sumporni, njega će spaliti."}]},"31":{"hr":[{"v":1,"t":"Teško onima što slaze u Egipat po pomoć i nadu u konje polažu te se uzdaju u mnoga kola i u mnoštvo konjanika, ne gledajuć' s uzdanjem u Sveca Izraelova i od Jahve savjeta ne tražeć'."},{"v":2,"t":"Al' i on je mudar i navalit će zlo, i neće poreć' svojih prijetnja; on će ustat' na dom zlikovački i na pomoć zločinačku."},{"v":3,"t":"Egipćanin je čovjek, a ne Bog; konji su mu meso, a ne duh; kada Jahve rukom mahne, posrnut će pomagač i past će onaj komu pomaže - svi će zajedno propasti."},{"v":4,"t":"Da, ovako mi reče Jahve: Kao što lav ili lavić nad plijenom reži, pa i kad se strči na njega mnoštvo pastira, on se ne prepada vike njihove, nit' za njihovu graju mari - tako će Jahve nad Vojskama sići da vojuje za goru Sion, za visinu njezinu."},{"v":5,"t":"Kao ptice što lepršaju krilima, Jahve nad Vojskama zaklanjat će Jeruzalem, zaklanjat' ga, izbaviti, poštedjet' ga i spasiti."},{"v":6,"t":"Vratite se onome od kog otpadoste tako duboko, sinovi Izraelovi."},{"v":7,"t":"Da, u onaj će dan svatko prezreti svoje kumire srebrne i zlatne što ih rukama sebi za grijeh načiniste."},{"v":8,"t":"Asur neće pasti od mača ljudskoga: proždrijet će ga mač, ali ne čovječji. Od mača će bježat', al' će mu satnici pod tlaku pasti."},{"v":9,"t":"Užasnut, ostavit će svoju hridinu, prestravljeni, knezovi od svoje će bježat' zastave - riječ je Jahve, čiji je oganj na Sionu i čija je peć u Jeruzalemu."}]},"32":{"hr":[{"v":1,"t":"Evo po pravdi kralj kraljuje, po pravici vladaju knezovi:"},{"v":2,"t":"svaki je kao zavjetrina, utočište od nevremena, kao u sušnoj zemlji potoci, kao sjena u žednoj pustari."},{"v":3,"t":"Oči vidovitih neće više biti slijepe, uši onih što čuju slušat će pozorno;"},{"v":4,"t":"srce nerazumnih shvaćat će mudrost, mucavci će govorit' okretno i razgovijetno;"},{"v":5,"t":"pokvarenjaka neće više zvati plemenitim, varalicu neće više držat' odličnikom."},{"v":6,"t":"Jer, pokvarenjak govori ludosti i srce mu bezakonje snuje, da počini zlodjela, da o Jahvi oholo govori; da gladnoga ostavi prazna želuca, da žednome napitak uskrati."},{"v":7,"t":"U varalice pakosno je oružje; on spletke samo kuje, da lažima upropasti uboge, pa i kad nevoljnik pravo dokazuje."},{"v":8,"t":"U plemenita nakane su plemenite i plemenito on djeluje."},{"v":9,"t":"Ustajte, žene nehajne, slušajte moj glas; kćeri lakoumne, čujte mi besjedu."},{"v":10,"t":"Za godinu i nekoliko dana drhtat ćete, lakoumnice, jer jematve neće biti, plodovi se neće brati."},{"v":11,"t":"Dršćite, nehajnice, strepite, lakoumnice, svucite se, obnažite, oko bedara kostrijet opašite!"},{"v":12,"t":"Bijte se u prsa zbog ljupkih polja, plodnih vinograda;"},{"v":13,"t":"zbog njiva naroda mojega što rađaju trnjem i dračem; zbog svih kuća veselih, grada razigranog."},{"v":14,"t":"Jer, napuštena bit će palača, opustjet će bučni grad; Ofel i kula postat će brlog dovijeka - bit će radost divljim magarcima, paša stadima,"},{"v":15,"t":"dok se na nas ne izlije duh iz visina. Tad će pustinja postat' voćnjak, a voćnjak se u šumu pretvorit'."},{"v":16,"t":"U pustinji će se nastaniti pravo, i pravda će prebivati u voćnjaku."},{"v":17,"t":"Mir će biti djelo pravde, a plod pravednosti - trajan pokoj i uzdanje."},{"v":18,"t":"Narod će moj prebivati u nastambama pouzdanim, u bezbrižnim počivalištima."},{"v":19,"t":"A šuma će biti oborena, grad će biti snižen."},{"v":20,"t":"Blago vama: sijat ćete kraj svih voda, puštajući vola i magarca da slobodno idu!"}]},"33":{"hr":[{"v":1,"t":"Teško tebi koji nepustošen pustošiš, koji pljačkaš nepljačkan, kad prestaneš, tebe će opustošiti, opljačkat' te kad prestaneš pljačkati."},{"v":2,"t":"Jahve, smiluj nam se, u te se uzdamo! Budi mišica naša svako jutro, naš spas u doba nevolje."},{"v":3,"t":"Od silna tutnja pobjegoše narodi, ti ustade, raspršiše se puci"},{"v":4,"t":"i plijen se skuplja kao što se kupe šaške, na nj će navaliti kao jato skakavaca."},{"v":5,"t":"Uzvišen je Jahve jer u visini stoluje, on puni Sion pravom i pravednošću."},{"v":6,"t":"Pouzdan je tvoj vijek: mudrost i znanje spasonosno su blago - a strah Gospodnji njegovo bogatstvo."},{"v":7,"t":"Gle, stanovništvo Arielovo kuka po ulicama, glasnici mironosni plaču gorko."},{"v":8,"t":"Opustješe ceste, s putova nesta putnika; raskidaju se savezi, preziru se svjedoci, ni prema kome nema obzira."},{"v":9,"t":"Gine zemlja u žalosti, u stidu vene Libanon. Šaron je kao stepa, Bašan i Karmel ogolješe."},{"v":10,"t":"“Sada ću ustati”, veli Jahve, “sada ću se dići, sada uzvisiti."},{"v":11,"t":"Začeste sijeno, rodit ćete slamu; dah moj proždrijet će vas kao oganj."},{"v":12,"t":"Narodi će biti sažgani u vapno, kao posječeno trnje što gori u vatri."},{"v":13,"t":"Čujte, vi koji ste daleko, što sam učinio, a vi koji ste blizu poznajte mi snagu!”"},{"v":14,"t":"Na Sionu strepe grešnici, trepet spopada bezbožnika: “Tko će od nas opstati pred ognjem zatornim, tko će od nas opstati pred žarom vječnim?”"},{"v":15,"t":"Onaj koji hodi u pravdi i pravo govori, koji prezire dobit od prinude, koji otresa ruku da ne primi mito, koji zatiskuje uši da ne čuje o krvoproliću, koji zatvara oči da ne vidi zlo:"},{"v":16,"t":"on će prebivati u visinama, tvrđe na stijenama bit će mu utočište, imat će dosta kruha i vode će mu svagda dotjecati."},{"v":17,"t":"Oči će ti gledati kralja u njegovoj ljepoti, promatrat će zemlju nepreglednu."},{"v":18,"t":"Srce će ti u strahu misliti: Gdje li je onaj što je brojio, gdje li onaj što je mjerio, gdje li onaj što je prebrajao mladiće?"},{"v":19,"t":"Nećeš više vidjeti divljega naroda, naroda nerazumljiva i neshvatljiva govora, jezika strana što ga nitko ne razumije."},{"v":20,"t":"Pogledaj na Sion, grad blagdana naših: oči će ti Jeruzalem vidjeti, prebivalište zaštićeno, šator što se ne prenosi, kojem se kolčići nikad ne vade, nit' mu se ijedno uže otkida."},{"v":21,"t":"Ondje nam je Jahve silni, umjesto rijeka i širokih rukavaca: neće onud proći nijedna lađa s veslima niti će koji bojni brod projedriti."},{"v":22,"t":"Jer Jahve je sudac naš, Jahve naš vojvoda, Jahve je kralj naš - on će nas spasiti."},{"v":23,"t":"Užad ti je popustila, ne može držati jarbola ni razviti stijega, pa se dijeli golemo blago oteto - kljasti će se naplijeniti plijena!"},{"v":24,"t":"I nijedan građanin neće reći: “Bolestan sam!” Narodu što živi ondje krivnja će se oprostiti."}]},"34":{"hr":[{"v":1,"t":"Pristupite, puci, da čujete, pomno slušajte, narodi; čuj, zemljo, i sve što te ispunja, kruže zemaljski i sve što raste po tebi!"},{"v":2,"t":"Jer razgnjevi se Jahve na sve narode, razjari se na svu vojsku njihovu. Izruči ih uništenju, pokolju ih predade."},{"v":3,"t":"Leže njihovi pobijeni, smrad se diže od trupla mnogih, krv gorama proteče,"},{"v":4,"t":"raspade se sva vojska nebeska. Nebesa se sviše kao knjiga i pada sva njihova vojska k'o što lozov list otpada, k'o što se trusi lišće smokovo."},{"v":5,"t":"Jer na nebu je opijeni mač moj: gle, na Edom on se obara da kazni narod što ga prokleh."},{"v":6,"t":"Mač Jahvin krvlju je opijen, omašćen pretilinom, krvlju janjećom i jarećom, pretilinom bubrega ovnujskih. Jer Jahvi se u Bosri žrtva prinosi, veliko klanje u zemlji edomskoj."},{"v":7,"t":"S njima će biti poklani bivoli i junad s bikovima. Zemlja će se njihovom napojiti krvlju, i prašina njihova omastit' pretilinom,"},{"v":8,"t":"jer Jahvi je ovo dan odmazde, godina naplate da Sion osveti."},{"v":9,"t":"Potoci se njegovi obrću u smolu, prašina njegova u sumpor, i zemlja će mu postat smola goreća."},{"v":10,"t":"Ni noću ni danju ugasit' se neće, dim će joj se dizati dovijeka, iz koljena u koljeno pusta će ostati, za vjekove vjekova nitko neće prolaziti njome."},{"v":11,"t":"Zaposjest će je jež i čaplja, sova i gavran prebivat će u njoj. Rastegnut će nad njom uže pustoši i visak praznine."},{"v":12,"t":"Ondje će se nastaniti jarci, neće biti više plemića njezinih, ondje se više neće proglašavat' kraljevi, svi će joj knezovi biti uništeni."},{"v":13,"t":"Nići će trnje u njenim dvorcima, u tvrđavama kopriva i stričak, ona će biti jazbina čagljima, ležaj nojevima."},{"v":14,"t":"Ondje će se sretat divlje mačke s hijenama, jarci će dozivati jedan drugoga; ondje će se odmarati Lilit našav počivalište."},{"v":15,"t":"Ondje će se gnijezditi guja, odlagati jaja, ležat' na njima, u sjeni ih tvojoj izleći; onamo će slijetati jastrebovi jedan za drugim."},{"v":16,"t":"Istražujte u knjizi Jahvinoj i čitajte, nijedno od tog ne izosta, jer usta njegova tako narediše i duh njegov njih sakupi."},{"v":17,"t":"Jer on im je ždrijeb bacio i ruka im njegova užetom zemlju odmjeri: dovijeka će je oni posjedovati, od koljena do koljena nju će obitavati."}]},"35":{"hr":[{"v":1,"t":"Nek' se uzraduje pustinja, zemlja sasušena, neka kliče stepa, nek' ljiljan procvjeta."},{"v":2,"t":"Nek' bujno cvatom cvate, da, neka od veselja kliče i nek' se raduje. Dana joj je slava Libanona, divota Karmela i Šarona; oni će vidjeti slavu Jahvinu, divotu Boga našega."},{"v":3,"t":"Ukrijepite ruke klonule, učvrstite koljena klecava!"},{"v":4,"t":"Recite preplašenim srcima: “Budite jaki, ne bojte se! Evo Boga vašega, odmazda dolazi, Božja naplata, on sam hita da nas spasi!”"},{"v":5,"t":"Sljepačke će oči progledati, uši će se gluhih otvoriti,"},{"v":6,"t":"tad će hromi skakati k'o jelen, njemakov će jezik klicati. Jer će u pustinji provreti voda, i u stepi potoci,"},{"v":7,"t":"sažgana će zemlja postat' jezero, a tlo žedno - izvori. U brlozima gdje ležahu čaglji izrast će rogoz i trska."},{"v":8,"t":"Bit će ondje čista cesta, a zvat će se Sveti put: nitko nečist njime neće proći, bezumnici njime neće lutati."},{"v":9,"t":"Ondje neće više biti lÓava, nit' će onud zvijer prolaziti, već će hodit' samo otkupljeni,"},{"v":10,"t":"vraćati se otkupljenici Jahvini. Doći će u Sion kličuć' od radosti, s veseljem vječnim na čelima; pratit će ih radost i veselje, pobjeći će bol i jauci."}]},"36":{"hr":[{"v":1,"t":"Četrnaeste godine Ezekijina kraljevanja asirski kralj Sanherib napade sve utvrđene judejske gradove i osvoji ih."},{"v":2,"t":"Tada pošalje asirski kralj iz Lakiša u Jeruzalem kralju Ezekiji velikoga peharnika s jakom vojskom. On stade kod vodovoda Gornjeg ribnjaka, na putu u Valjarevo polje."},{"v":3,"t":"K njemu iziđe upravitelj dvora Elijakim, sin Hilkijin, pisar Šebna i savjetnik Joah, sin Asafov."},{"v":4,"t":"Veliki im peharnik reče: “Kažite Ezekiji: Ovako govori veliki kralj, kralj asirski: 'Kakvo je to uzdanje u koje se uzdaš?"},{"v":5,"t":"Misliš li da su prazne riječi već i savjet i snaga za rat? U koga se uzdaš da si se pobunio protiv mene?"},{"v":6,"t":"Eto, oslanjaš se na Egipat, na slomljenu trsku koja prodire i probada dlan onomu tko se na nju nasloni. Takav je faraon, kralj egipatski, svima koji se uzdaju u njega.'"},{"v":7,"t":"Možda ćete mi odgovoriti: 'Uzdamo se u Jahvu, Boga svojega.' Ali nije li njemu Ezekija uklonio uzvišice i žrtvenike i zapovjedio Judejcima i Jeruzalemu: 'Samo se pred ovim žrtvenikom klanjajte!'"},{"v":8,"t":"Hajde, okladi se s mojim gospodarom, kraljem asirskim: dat ću ti dvije tisuće konja ako mogneš naći jahače za njih."},{"v":9,"t":"Kako ćeš onda odoljeti jednome jedinom od najmanjih slugu moga gospodara? Ali ti se uzdaš u Egipat da će ti dati kola i konjanike!"},{"v":10,"t":"Naposljetku, zar sam ja mimo volju Jahvinu krenuo protiv ove zemlje da je razorim? Sam mi je Jahve rekao: 'Idi na tu zemlju i razori je!'”"},{"v":11,"t":"Elijakim, Šebna i Joah rekoše velikom peharniku: “Molimo te, govori svojim slugama aramejski, jer mi razumijemo; ne govori s nama judejski da čuje narod koji je na zidinama.”"},{"v":12,"t":"Ali im veliki peharnik odgovori: “Zar me moj gospodar poslao da ovo kažem tvojem gospodaru i tebi, a ne upravo onim ljudima koji sjede na zidinama, osuđeni da s vama jedu svoju nečist i piju svoju mokraću?”"},{"v":13,"t":"Tada se veliki peharnik uspravi i u sav glas povika na judejskom ove riječi: “Čujte riječ velikoga kralja, kralja asirskoga!"},{"v":14,"t":"Ovako veli kralj: 'Neka vas Ezekija ne zavarava, jer vas ne može izbaviti iz moje ruke."},{"v":15,"t":"Neka vas Ezekija ne hrabri pouzdanjem u Jahvu govoreći: Jahve će nas sigurno izbaviti: ovaj grad neće pasti u ruke kralju asirskom."},{"v":16,"t":"Ne slušajte Ezekije, jer ovako veli asirski kralj: Sklopite mir sa mnom, predajte mi se, pa neka svaki od vas jede plodove iz svoga vinograda i sa svoje smokve i neka pije vode iz svojega studenca"},{"v":17,"t":"dok ne dođem i ne odvedem vas u zemlju kao što je vaša, u zemlju pšenice i mošta, u zemlju kruha i vinograda."},{"v":18,"t":"Ne dajte da vas Ezekija zaludi govoreći vam: Jahve će vas izbaviti. Jesu li bogovi drugih naroda izbavili svoje zemlje iz ruku asirskoga kralja?"},{"v":19,"t":"Gdje su bogovi hamatski i arpadski, gdje su bogovi sefarvajimski, gdje su bogovi samarijski da izbave Samariju iz moje ruke?"},{"v":20,"t":"Koji su među svim bogovima tih zemalja izbavili svoju zemlju iz moje ruke, da bi Jahve izbavio Jeruzalem iz ruke moje?'”"},{"v":21,"t":"Šutjeli su i ni riječi mu nisu odgovorili, jer kralj bijaše zapovjedio: “Ne odgovarajte mu!”"},{"v":22,"t":"Upravitelj dvora Elijakim, sin Hilkijin, pisar Šebna i savjetnik Joah, sin Asafov, dođoše k Ezekiji, razdrijevši haljine, i saopćiše mu riječi velikoga peharnika."}]},"37":{"hr":[{"v":1,"t":"Čuvši to, kralj Ezekija razdrije svoje haljine, obuče kostrijet i ode u Dom Jahvin."},{"v":2,"t":"Zatim posla Elijakima, upravitelja dvora, kraljevskog pisara Šebnu i svećeničke starješine, odjevene u kostrijet, k proroku Izaiji, sinu Amosovu."},{"v":3,"t":"Oni mu rekoše: “Ovako veli Ezekija: 'Ovo je dan nevolje, kazne i rugla: prispješe djeca do porođaja, a nema snage da se rode."},{"v":4,"t":"Možda je Jahve, Bog tvoj, čuo riječi velikog peharnika koga je kralj asirski, gospodar njegov, poslao da se izruguje Bogu živome, i možda će Jahve, Bog tvoj, kazniti riječi koje je čuo! Pomoli se pobožno za Ostatak koji je još preostao!'”"},{"v":5,"t":"Kad su sluge kralja Ezekije stigle k Izaiji,"},{"v":6,"t":"on im reče: “Kažite svome gospodaru: 'Ovako veli Jahve: Ne boj se riječi koje si čuo kada su na me hulile sluge kralja asirskoga."},{"v":7,"t":"Udahnut ću u njega duh, i kad čuje jednu vijest, vratit će se u svoju zemlju. I učinit ću da u svojoj zemlji pogine od mača.'”"},{"v":8,"t":"Veliki peharnik vrati se i nađe asirskoga kralja gdje opsjeda Libnu, jer bijaše čuo da je kralj otišao iz Lakiša."},{"v":9,"t":"Dočuo je, naime, da je Tirhaka, etiopski kralj, zavojštio na njega. Tada Sanherib ponovo uputi poslanike da kažu Ezekiji:"},{"v":10,"t":"“Ovako recite judejskom kralju Ezekiji: 'Neka te ne vara tvoj Bog, u koga se uzdaš, govoreći ti: Jeruzalem neće pasti u ruke asirskog kralja."},{"v":11,"t":"Ti znaš što su kraljevi asirski učinili svim zemljama izručivši ih prokletstvu! A ti, ti li ćeš se spasiti?"},{"v":12,"t":"Jesu li bogovi spasili narode koje su uništili moji oci: Gozance, Harance, Resefce i Edence, u Tel Basaru?"},{"v":13,"t":"Gdje je kralj hamatski, kralj arpadski, kralj Sefarvajima, Hene i Ive?'”"},{"v":14,"t":"Ezekija primi pismo iz ruke poslanikove i pročita ga. Zatim uđe u Dom Jahvin i razvi ga ondje pred Jahvom."},{"v":15,"t":"I pomoli se Ezekija Jahvi ovako:"},{"v":16,"t":"“Jahve nad Vojskama, Bože Izraelov, koji stoluješ nad kerubima, ti si Bog jedini nad svim kraljevstvima na zemlji, ti si stvorio nebo i zemlju."},{"v":17,"t":"Prikloni uho, Jahve, i počuj! Otvori oči, Jahve, i vidi! Sanheribove čujder riječi koje poruči da izruga Boga živoga."},{"v":18,"t":"Istina je, o Jahve, asirski su kraljevi zatrli sve narode i zemlje njihove;"},{"v":19,"t":"pobacali im u oganj bogove, jer ne bijahu bogovi to, već djela ruku ljudskih, od drva i kamena; zato ih i uništiše."},{"v":20,"t":"Ali sada, Jahve, Bože naš, izbavi nas iz ruke njegove, da spoznaju sva kraljevstva zemlje da si ti, Jahve, Bog jedini!”"},{"v":21,"t":"Tad Izaija, sin Amosov, poruči Ezekiji: “Ovako veli Jahve, Bog Izraelov: 'Uslišah molitvu koju mi uputi zbog Sanheriba, kralja asirskoga.'"},{"v":22,"t":"Evo riječi što je Jahve objavi protiv njega: Prezire te, ruga ti se, djevica, Kći sionska; za tobom maše glavom kći jeruzalemska."},{"v":23,"t":"Koga si grdio, hulio? Na koga si glasno vikao, ohol pogled dizao? Na Sveca Izraelova!"},{"v":24,"t":"Po slugama si svojim vrijeđao Gospoda. Govorio si: s mnoštvom kola ja popeh se na vrh gorÄa, na najviše vrhunce Libanona. Posjekoh mu ja cedre najviše i čemprese ponajljepše. Dosegoh mu vrh najviši, i vrt njegov šumoviti."},{"v":25,"t":"Kopao sam i pio sam vode tuđe; stopalima tad isuših sve rijeke egipatske."},{"v":26,"t":"Čuješ li dobro? Odavna to sam snovao, odiskona smišljao, sada to ostvarujem: na tebi je da prometneš gradove tvrde u razvaline;"},{"v":27,"t":"stanovnici njini, nemoćni, prepadnuti i smeteni, bjehu kao trava u polju kao mlado zelenilo, kao trava vrh krovova opaljena vjetrom istočnim."},{"v":28,"t":"Znam kad se dižeš i kad sjedaš, kad izlaziš i kad se vraćaš."},{"v":29,"t":"Jer bjesnio si na me i jer obijest tvoja do ušiju mi dođe, prsten ću ti provući kroz nozdrve, uzde stavit' u žvale, vratit ću te putem kojim si došao!"},{"v":30,"t":"A znak nek' ti bude ovo: ove će se godine jesti što se samo okrÄunÄi, dogodine što samo uzraste, a treće godine sijte i žanjite, sadite vinograde, jedite im rod."},{"v":31,"t":"Preživjeli iz kuće Judine, žilje će pustit' u dubinu, plodom rodit' u visinu."},{"v":32,"t":"Jer će iz Jeruzalema izaći Ostatak. Sačuvani s gore Siona. Sve će to učinit' ljubomora Jahve nad Vojskama."},{"v":33,"t":"Zato ovo govori Jahve o kralju asirskom: U ovaj grad on ući neće, ovamo strijele svoje neće izmetati, k njemu neće ni štit okrenuti, niti oko njega nasipe kopati."},{"v":34,"t":"Vratit će se putem kojim je i došao, u grad ovaj neće ući - riječ je Jahvina."},{"v":35,"t":"Grad ću ovaj štitit, zakriliti ga, sebe radi i rad sluge svoga Davida.”"},{"v":36,"t":"Tad iziđe Anđeo Jahvin i pobi u asirskom taboru sto osamdeset i pet tisuća ljudi. Ujutru, kad je valjalo ustati, gle, bijahu ondje sve sami mrtvaci."},{"v":37,"t":"Sanherib podiže tabor i ode. Vratio se u Ninivu."},{"v":38,"t":"Jednoga dana, dok se klanjao u hramu svoga boga Nimroka, njegovi ga sinovi Adramelek i Sareser ubiše mačem i pobjegoše u zemlju araratsku. Na njegovo se mjesto zakralji sin mu Asar-Hadon."}]},"38":{"hr":[{"v":1,"t":"U ono se vrijeme Ezekija razbolje nasmrt. Prorok Izaija, sin Amosov, dođe mu i reče: “Ovako veli Jahve: 'Uredi kuću svoju, jer ćeš umrijeti, nećeš ozdraviti.'”"},{"v":2,"t":"Ezekija se okrenu zidu i ovako se pomoli Jahvi:"},{"v":3,"t":"“Ah, Jahve, sjeti se da sam pred tobom hodio vjerno i poštena srca i učinio što je dobro u tvojim očima.” I Ezekija briznu u gorak plač."},{"v":4,"t":"Tada dođe riječ Jahvina Izaiji:"},{"v":5,"t":"“Idi i reci Ezekiji: Ovako kaže Jahve, Bog oca tvoga Davida: 'Uslišao sam tvoju molitvu, vidio tvoje suze. Izliječit ću te; za tri dana uzići ćeš u Dom Jahvin. Dodat ću tvome vijeku petnaest godina."},{"v":6,"t":"Izbavit ću tebe i ovaj grad iz ruku asirskoga kralja. Jest, zakrilit ću ovaj grad!'”"},{"v":7,"t":"Izaija odgovori: “Evo ti znaka od Jahve da će učiniti što je rekao:"},{"v":8,"t":"sjenu koja je sišla po stupnjevima Ahazova sunčanika vratit ću za deset stupnjeva natrag.” I vrati se sunce deset stupnjeva natrag po stupnjevima po kojima bijaše već sišlo."},{"v":9,"t":"Pjesan Ezekije, kralja judejskoga, kada se razbolio pa ozdravio od svoje bolesti:"},{"v":10,"t":"“Govorio sam: U podne dana svojih ja moram otići. Na vratima Podzemlja mjesto mi je dano za ostatak mojih ljeta."},{"v":11,"t":"Govorio sam: Vidjet više neću Jahve na zemlji živih, vidjet više neću nikoga od stanovnika ovog svijeta."},{"v":12,"t":"Stan je moj razvrgnut, bačen daleko, kao šator pastirski; poput tkalca moj si život namotao da bi me otkinuo od osnove. Od jutra do noći skončat ćeš me,"},{"v":13,"t":"vičem sve do jutra; kao što lav mrska kosti moje, od jutra do noći skončat ćeš me."},{"v":14,"t":"Poput laste ja pijučem, zapomažem kao golubica, uzgor mi se okreću oči, zauzmi se, jamči za me."},{"v":15,"t":"Kako ću mu govoriti i što ću mu reći? TÓa on je koji djeluje. Slavit ću te sva ljeta svoja, premda s gorčinom u duši."},{"v":16,"t":"Gospodine, za tebe živjet će srce moje i živjet će moj duh. Ti ćeš me izliječiti i vratiti mi život,"},{"v":17,"t":"bolest će mi se pretvorit' u zdravlje. Ti si spasio dušu moju od jame uništenja, za leđa si bacio sve moje grijehe."},{"v":18,"t":"Jer Podzemlje ne slavi te, ne hvali te Smrt; oni koji padnu u rupu u tvoju se vjernost više ne uzdaju."},{"v":19,"t":"Živi, živi, jedino on te slavi kao ja danas. Otac naučava sinovima tvoju vjernost."},{"v":20,"t":"U pomoć mi, Jahve priteci, i mi ćemo pjevati uz harfe sve dane svojega života pred Hramom Jahvinim.”"},{"v":21,"t":"Izaija naloži: “Donesite oblog od smokava, privijte mu ga na čir i on će ozdraviti.”"},{"v":22,"t":"Ezekija upita: “Po kojem ću znaku prepoznati da ću uzići u Dom Jahvin?”"}]},"39":{"hr":[{"v":1,"t":"U to vrijeme posla babilonski kralj Merodak Baladan, sin Baladanov, pisma s darom Ezekiji, jer bijaše čuo da se razbolio i ozdravio."},{"v":2,"t":"Ezekija se obradova tome i pokaza poslanicima svoju riznicu - srebro, zlato, miomirise i mirisavo ulje - svoju oružanu i sve što je bilo u skladištima. Nije bilo ničega u njegovu dvoru i u svemu njegovu gospodarstvu što im Ezekija nije pokazao."},{"v":3,"t":"Tada prorok Izaija dođe kralju Ezekiji i upita ga: “Što su rekli ti ljudi i odakle su došli k tebi?” Ezekija odgovori: “Došli su iz daleke zemlje, iz Babilona.”"},{"v":4,"t":"Izaija upita dalje: “Što su vidjeli u tvojem dvoru?” Ezekija odgovori: “Vidjeli su sve što je u mojem dvoru; nema u mojim skladištima ničega što im nisam pokazao.”"},{"v":5,"t":"Tad Izaija reče Ezekiji: “Čuj riječ Jahve nad Vojskama:"},{"v":6,"t":"'Evo dolaze dani kada će sve što je u tvojem dvoru, sve što su tvoji oci nakupili do danas, biti odneseno u Babilon. Ništa neće ostati,' kaže Jahve."},{"v":7,"t":"'A od sinova koji poteku od tebe, koji ti se rode, neke će uzeti da budu uškopljeni dvorani babilonskoga kralja.'”"},{"v":8,"t":"Ezekija odgovori Izaiji: “Povoljna je riječ koju ti je Jahve objavio.” A mislio je: “Bit će barem mira i sigurnosti za moga života.”"}]},"40":{"hr":[{"v":1,"t":"“Tješite, tješite moj narod, govori Bog vaš."},{"v":2,"t":"Govorite srcu Jeruzalema, vičite mu da mu se ropstvo okonča, da mu je krivnja okajana, jer iz Jahvine ruke primi dvostruko za sve grijehe svoje.”"},{"v":3,"t":"Glas viče: “Pripravite Jahvi put kroz pustinju. Poravnajte u stepi stazu Bogu našemu."},{"v":4,"t":"Nek' se povisi svaka dolina, nek' se spusti svaka gora i brežuljak. Što je neravno, nek' se poravna, strmine nek' postanu ravni."},{"v":5,"t":"Otkrit će se tada Slava Jahvina i svako će je tijelo vidjeti, jer Jahvina su usta govorila.”"},{"v":6,"t":"Glas nalaže: “Viči!” Odgovorih: “Što da vičem?” - “Svako je tijelo k'o trava, k'o cvijet poljski sva mu dražest."},{"v":7,"t":"Sahne trava, vene cvijet, kad dah Jahvin preko njih prođe. Doista, narod je trava."},{"v":8,"t":"Sahne trava, vene cvijet, ali riječ Boga našeg ostaje dovijeka.”"},{"v":9,"t":"Na visoku se uspni goru, glasniče radosne vijesti, Sione! Podigni snažno svoj glas, glasniče radosne vijesti, Jeruzaleme! Podigni ga, ne boj se, reci judejskim gradovima: “Evo Boga vašega!”"},{"v":10,"t":"Gle, Gospod Jahve dolazi u moći, mišicom svojom vlada! Evo s njim naplata njegova, a ispred njega njegova nagrada."},{"v":11,"t":"Kao pastir pase stado svoje, u ruke uzima jaganjce, nosi ih u svome naručju i brižljivo njeguje dojilice."},{"v":12,"t":"Tko je šakom izmjerio more i nebesa premjerio pedljem? Tko je mjericom izmjerio zemlju i planine na mjerila, a tezuljom bregove?"},{"v":13,"t":"Tko je pokrenuo duh Jahvin, koji ga je uputio savjetnik?"},{"v":14,"t":"S kim se on posvjetova, tko je njemu mudrost ulio, naučio ga putovima pravde? Tko li ga je naučio znanju, pokazao mu put k umnosti?"},{"v":15,"t":"Gle, narodi su kao kap iz vjedra, vrijede kao prah na tezulji. Otoci, gle, lebde poput truna!"},{"v":16,"t":"Libanon je malen za lomaču, a zvijeri njegovih nema dosta za paljenicu."},{"v":17,"t":"Svi narodi k'o ništa su pred njim, ništavilo su njemu i praznina."},{"v":18,"t":"S kime ćete prispodobit' Boga? I s kakvim ga likom usporedit'?"},{"v":19,"t":"Ljevač lijeva idol, zlatar ga pozlaćuje i lijeva od srebra lančiće."},{"v":20,"t":"Siromah za prinos bira drvo koje ne trune; i vješta traži umjetnika. da mu načini kip nepomičan."},{"v":21,"t":"Zar ne znate? Zar niste čuli? Nije li vam odiskona otkriveno? Zar niste shvatili tko zasnova zemlju?"},{"v":22,"t":"On stoluje vrh kruga zemaljskoga kom su stanovnici poput skakavaca. Kao zastor nebesa je razastro, kao šator za stan razapeo."},{"v":23,"t":"On obraća u ništa knezove, uništava suce zemaljske."},{"v":24,"t":"Tek što su zasađeni, tek što su posijani, tek što im stabljika u zemlju korijen pruži, on puhne na njih i oni posahnu, vihor ih k'o pljevu raznese."},{"v":25,"t":"“S kime ćete mene prispodobit', tko mi je ravan?” - kaže Svetac."},{"v":26,"t":"Podignite oči i gledajte: tko je to stvorio? Onaj koji na broj izvodi vojsku njihovu i koji ih sve zove po imenu."},{"v":27,"t":"Zašto kažeš, Jakove, i ti, Izraele, govoriš: “Moj put sakriven je Jahvi, Bogu mom izmiče moja pravica?”"},{"v":28,"t":"Zar ne znaš? Zar nisi čuo? Jahve je Bog vječni, krajeva zemaljskih stvoritelj. On se ne umara, ne sustaje, i um je njegov neizmjerljiv."},{"v":29,"t":"Umornome snagu vraća, jača nemoćnoga."},{"v":30,"t":"Mladići se more i malakšu, iznemogli, momci posrću."},{"v":31,"t":"Al' onima što se u Jahvu uzdaju snaga se obnavlja, krila im rastu kao orlovima, trče i ne sustaju, hode i ne more se."}]},"41":{"hr":[{"v":1,"t":"Umuknite preda mnom, otoci, nek' novu snagu narodi priberu. Nek' se primaknu i progovore; zajedno pristupimo k sudu."},{"v":2,"t":"“Tko je podigao s Istoka onog kog ukorak prati Pobjeda? Tko mu izručuje narode i kraljeve podlaže? Prah su pod mačem njegovim, k'o pljevu ih njegov luk raspršuje."},{"v":3,"t":"Goni ih, napreduje pouzdano, noge mu se ceste ne dotiču."},{"v":4,"t":"Tko je to učinio i izvršio? Onaj koji odiskona zove naraštaje, ja, Jahve, koji sam prvi i bit ću ovaj isti s posljednjima!”"},{"v":5,"t":"Otoci gledaju i strah ih obuzima, dršću krajevi zemaljski, oni se bliže i već su tu."},{"v":6,"t":"Svatko pomaže svome drugu i bratu svom zbori: “Hrabro!”"},{"v":7,"t":"Ljevač bodri zlatara, onaj koji gladi čekićem bodri onog koji kuje na nakovnju. On govori o spajanju: “Dobro je”, i čavlima kip učvršćuje da se ne pomiče."},{"v":8,"t":"Ti, Izraele, slugo moja, Jakove, kog sam izabrao, potomče Abrahama, mojega ljubimca!"},{"v":9,"t":"Ti koga uzeh s krajeva zemlje i pozvah s rubova njenih, ti kome rekoh: “Ti si sluga moj, izabrao sam te i nisam te odbacio.”"},{"v":10,"t":"Ne boj se jer ja sam s tobom; ne obaziri se plaho jer ja sam Bog tvoj. Ja te krijepim i pomažem ti, podupirem te pobjedničkom desnicom."},{"v":11,"t":"Gle, postidjet će se i smesti svi koji su na tebe bjesnjeli, bit će uništeni i propast će oni što se s tobom parbiše!"},{"v":12,"t":"Tražit ćeš svoje protivnike, ali ih nećeš naći. Bit će uništeni, svedeni na ništa oni koji protiv tebe vojuju."},{"v":13,"t":"Jer ja, Jahve, Bog tvoj, krijepim desnicu tvoju i kažem ti: “Ne boj se, ja ti pomažem.”"},{"v":14,"t":"Ne boj se, Jakove, crviću, Izraele, ličinko, ja sam pomoć tvoja - riječ je Jahvina - Svetac Izraelov tvoj je otkupitelj."},{"v":15,"t":"Gle, činim te mlatilom oštrim, novim, dvostrukih zubaca; mlatit ćeš i satirati brda, u prah ćeš pretvoriti bregove."},{"v":16,"t":"Vijat ćeš ih, vjetar će ih odnijeti, vihor će ih raspršiti. A ti ćeš kliktati u Jahvi, dičit ćeš se Svecem Izraelovim."},{"v":17,"t":"Ubogi i bijedni vodu traže, a nje nema! Jezik im se osuši od žeđi. Ja, Jahve, njih ću uslišiti, ja, Bog Izraelov, ostavit' ih neću."},{"v":18,"t":"U goleti bregova otvorit ću rijeke i posred dolova izvore. Pustinju ću pretvoriti u močvaru, a u vrela sušnu zemlju."},{"v":19,"t":"Posadit ću u pustinji cedar, bagrem, mirtu i maslinu. Stepu ću pošumiti čempresom, brijestom i šimširom zajedno."},{"v":20,"t":"Nek' svi vide i nek' znaju, nek' promisle i nek' shvate: ruka Jahvina to učini, Svetac Izraelov stvori sve."},{"v":21,"t":"“Iznesite svoj spor, kaže Jahve, predočite dokaze, kaže kralj Jakovljev."},{"v":22,"t":"Nek' pristupe i nek' nam objave ono što će se zbiti. TÓa što su nam otkrili o onom što bijaše, što se ispunilo, da o tom mislimo? Il' objavite što će biti, da doznamo ono što dolazi."},{"v":23,"t":"Otkrijte nam što će se poslije zbiti, i poznat ćemo da ste bogovi. Učinite nešto, dobro ili zlo, da se začudimo i prepadnemo zajedno."},{"v":24,"t":"Ali vi niste ništa i djela su vam ništavna, gnusan je koji vas izabere.”"},{"v":25,"t":"Podigoh ga sa sjevera da dođe, zazvah ga po imenu s istoka. Kao blato gazio je namjesnike, kao što po glini lončar gazi."},{"v":26,"t":"Tko je to odiskona objavio da bismo znali, unaprijed prorekao da bismo rekli: istina je? Ali nikog nema tko bi objavio, niti koga da bi navijestio, niti koga da čuje riječi vaše."},{"v":27,"t":"Ja prvi rekoh Sionu: “Gle, evo ih”; prvi Jeruzalemu poslah glasnika vijesti radosne."},{"v":28,"t":"Gledao sam, ali ne bješe nikoga, ni jednoga od njih da savjet dade, da ih pitam i da odgovore."},{"v":29,"t":"Svi zajedno ništa su, ništavna su djela njihova, vjetar i ispraznost njihovi kipovi."}]},"42":{"hr":[{"v":1,"t":"Evo Sluge mojega koga podupirem, mog izabranika, miljenika duše moje. Na njega sam svoga duha izlio da donosi pravo narodima."},{"v":2,"t":"On ne viče, on ne diže glasa, niti se čuti može po ulicama."},{"v":3,"t":"On ne lomi napuknutu trsku niti gasi stijenj što tinja. Vjerno on donosi pravdu,"},{"v":4,"t":"ne sustaje i ne malakše dok na zemlji ne uspostavi pravo. Otoci žude za njegovim naukom."},{"v":5,"t":"Ovako govori Jahve, Bog, koji stvori i razastrije nebesa, koji rasprostrije zemlju i njeno raslinje, koji dade dah narodima na njoj i dah bićima što njome hode."},{"v":6,"t":"Ja, Jahve, u pravdi te pozvah, čvrsto te za ruku uzeh; oblikovah te i postavih te za Savez narodu i svjetlost pucima,"},{"v":7,"t":"da otvoriš oči slijepima, da izvedeš sužnje iz zatvora, iz tamnice one što žive u tami."},{"v":8,"t":"Ja, Jahve mi je ime, svoje slave drugom ne dam, niti časti svoje kipovima."},{"v":9,"t":"Što prije prorekoh, evo, zbi se, i nove događaje ja naviještam, i prije negoli se pokažu, vama ih objavljujem."},{"v":10,"t":"Pjevajte Jahvi pjesmu novu, i s kraja zemlje hvalu njegovu, neka ga slavi more sa svim što je u njem, otoci i njihovi žitelji!"},{"v":11,"t":"Nek' digne glas pustinja i njeni gradovi, nek' odjeknu naselja gdje žive Kedarci! Nek' podvikuju stanovnici Stijene, neka kliču s gorskih vrhova!"},{"v":12,"t":"Nek' daju čast Jahvi i hvalu mu naviještaju po otocima!"},{"v":13,"t":"Kao junak izlazi Jahve, kao ratnik žar svoj podjaruje. Uz bojni poklik i viku ratnu ide junački na svog neprijatelja."},{"v":14,"t":"“Šutjeh dugo, gluh se činjah, svladavah se; sad vičem kao žena kada rađa, dašćem i uzdišem."},{"v":15,"t":"Isušit ću brda i bregove, sparušiti svu zelen po njima, rijeke ću u stepe pretvoriti i močvare isušiti."},{"v":16,"t":"Vodit ću slijepce po cestama, uputit' ih putovima. Pred njima ću tamu u svjetlost obratit', a neravno tlo u ravno. To ću učiniti i neću propustiti."},{"v":17,"t":"Uzmaknut će u golemu stidu koji se uzdaju u kipove, koji ljevenim likovima govore: 'Vi ste naši bogovi.'”"},{"v":18,"t":"Čujte, gluhi! Progledajte, slijepi, da vidite!"},{"v":19,"t":"Tko je slijep ako ne moj sluga, tko je gluh kao glasnik koga šaljem? Tko je slijep kao prijatelj, tko je gluh kao sluga Jahvin?"},{"v":20,"t":"Mnogo si vidio, ali nisi mario, uši ti bjehu otvorene, ali nisi čuo!"},{"v":21,"t":"Jahvi se svidjelo zbog njegove pravednosti da uzveliča i proslavi Zakon svoj."},{"v":22,"t":"A narod je ovaj opljačkan i oplijenjen, mladići mu stavljeni u klade, vrgnuti u zatvore. Plijene ih, a nikoga da ih izbavi; robe ih, a nitko da kaže: “Vrati!”"},{"v":23,"t":"Tko od vas mari za to? Tko pazi i sluša unapredak?"},{"v":24,"t":"Tko je pljačkašu izručio Jakova i otimačima Izraela? Nije li Jahve, protiv koga smo griješili, čijim putima ne htjedosmo hoditi, čiji Zakon nismo slušali?"},{"v":25,"t":"Zato izli na Izraela žarki gnjev svoj i strahote ratne: plamen ga okruži odasvud, al' on ni to nije shvatio; sažeže ga, al' on ni to k srcu ne uze."}]},"43":{"hr":[{"v":1,"t":"Sada ovako govori Jahve, koji te stvorio, Jakove, koji te sazdao, Izraele: “Ne boj se, jer ja sam te otkupio; imenom sam te zazvao: ti si moj!"},{"v":2,"t":"Kad preko vode prelaziš, s tobom sam; ili preko rijeke, neće te preplaviti. Pođeš li kroz vatru, nećeš izgorjeti, plamen te opaliti neće."},{"v":3,"t":"Jer ja sam Jahve, Bog tvoj, Svetac Izraelov, tvoj spasitelj. Za otkupninu tvoju dajem Egipat, mjesto tebe dajem Kuš i Šebu."},{"v":4,"t":"Jer dragocjen si u mojim očima, vrijedan si i ja te ljubim. Stog i dajem ljude za tebe i narode za život tvoj."},{"v":5,"t":"Ne boj se jer ja sam s tobom. S istoka ću ti dovest' potomstvo i sabrat ću te sa zapada."},{"v":6,"t":"Reći ću sjeveru: 'Daj mi ga!' a jugu 'Ne zadržavaj ga!' Sinove mi dovedi izdaleka i kćeri moje s kraja zemlje,"},{"v":7,"t":"sve koji se mojim zovu imenom i koje sam na svoju slavu stvorio, koje sam sazdao i načinio.”"},{"v":8,"t":"Izvedi narod slijep, premda oči ima, i gluh, premda uši ima."},{"v":9,"t":"Neka se saberu sva plemena i neka se skupe narodi. Tko je od njih to prorekao i davno navijestio? Nek' dovedu svjedoke da se opravdaju, neka se čuje da se može reći: “Istina je!”"},{"v":10,"t":"Jer vi ste mi svjedoci, riječ je Jahvina, i moje sluge koje sam izabrao, da biste znali i vjerovali i uvidjeli da sam to ja. Prije mene nijedan bog nije bio načinjen i neće poslije mene biti."},{"v":11,"t":"Ja, ja sam Jahve, osim mene nema spasitelja."},{"v":12,"t":"Ja sam prorekao, spasio i navijestio, i nema među vama tuđinca! Vi ste mi svjedoci, riječ je Jahvina, a ja sam Bog"},{"v":13,"t":"od vječnosti - ja jesam! I nitko iz ruke moje ne izbavlja; što učinim, tko izmijeniti može?"},{"v":14,"t":"Ovako govori Jahve, otkupitelj vaš, Svetac Izraelov: “Radi vas poslah protiv Babilona, oborit ću prijevornice zatvorima i Kaldejci će udarit u kukanje."},{"v":15,"t":"Ja sam Jahve, Svetac vaš, stvoritelj Izraelov, kralj vaš!”"},{"v":16,"t":"Ovako govori Jahve, koji put po moru načini i stazu po vodama silnim;"},{"v":17,"t":"koji izvede bojna kola i konje, vojsku i junake, i oni padoše da više ne ustanu, zgasnuše, kao stijenj se utrnuše."},{"v":18,"t":"Ne spominjite se onog što se zbilo, nit' mislite na ono što je prošlo."},{"v":19,"t":"Evo, činim nešto novo; već nastaje. Zar ne opažate? Da, put ću napraviti u pustinji, a staze u pustoši."},{"v":20,"t":"Slavit će me divlje zvijeri, čaglji i nojevi, jer vodu ću stvorit' u pustinji, rijeke u stepi, da napojim svoj narod, izabranika svoga."},{"v":21,"t":"I narod koji sam sebi sazdao moju će kazivati hvalu!"},{"v":22,"t":"Ali me ti, Jakove, nisi zazvao, niti si se zamorio oko mene, Izraele!"},{"v":23,"t":"Nisi mi prinosio ovce za paljenicu, nisi me častio žrtvama. A ja te silio nisam na prinose, nisam ti dodijavao ištući kada."},{"v":24,"t":"Nisi mi kupovao za novac trsku, nisi me sitio salom svojih žrtava; nego si me grijesima svojim mučio, bezakonjem svojim dosađivao mi."},{"v":25,"t":"A ja, ja radi sebe opačine tvoje brišem i grijeha se tvojih ne spominjem."},{"v":26,"t":"Podsjeti me, zajedno se sporimo, govori ti da se opravdaš."},{"v":27,"t":"Prvi je otac tvoj sagriješio, posrednici tvoji od mene se odmetnuli,"},{"v":28,"t":"knezovi su tvoji oskvrnuli Svetište. Tad izručih Jakova prokletstvu, i poruzi Izraela."}]},"44":{"hr":[{"v":1,"t":"Sad čuj, Jakove, slugo moj, Izraele, kog sam izabrao."},{"v":2,"t":"Ovako kaže Jahve, koji te stvorio, koji te od utrobe sazdao i pomaže ti: “Ne boj se, Jakove, slugo moja, Ješurune, kog sam izabrao."},{"v":3,"t":"Jer na žednu ću zemlju vodu izliti i po tlu sušnome potoke. Izlit ću duh svoj na tvoje potomstvo i blagoslov na tvoja pokoljenja."},{"v":4,"t":"Rast će kao trava pokraj izvora, kao vrbe uz vode tekućice."},{"v":5,"t":"Jedan će reći: 'Ja sam Jahvin', drugi će se zvati imenom Jakovljevim. Treći će sebi na ruci napisati: 'Jahvin' i nazvat će se imenom Izraelovim.”"},{"v":6,"t":"Ovako govori kralj Izraelov i otkupitelj njegov, Jahve nad Vojskama: “Ja sam prvi i ja sam posljednji: osim mene Boga nema."},{"v":7,"t":"Tko je kao ja? Nek' ustane i govori, nek' navijesti i nek' mi razloži! Tko je od vječnosti otkrio što se zbilo? Nek' nam navijesti što će još doći!"},{"v":8,"t":"Ne plašite se, ne bojte se: nisam li vam to odavna navijestio i otkrio? Vi ste mi svjedoci: ima li Boga osim mene? Ima li Stijene? Ja ne znam!”"},{"v":9,"t":"Tko god pravi kipove, ništavan je, i dragocjenosti njegove ne koriste ničemu. Svjedoci njihovi ništa ne vide i ništa ne znaju, da im budu na sramotu."},{"v":10,"t":"Tko pravi boga i lijeva kip da od toga korist ne očekuje?"},{"v":11,"t":"Gle, svi će štovatelji likova biti osramoćeni, izrađivači njihovi više od bilo koga. Nek' se saberu svi i pojave: prepast će se i postidjeti odjednom."},{"v":12,"t":"Kovač ga izrađuje na živu ugljevlju, čekićem ga oblikuje, snažnom ga rukom obrađuje. Gladan je i iznemogao; ne pije vode, iscrpljuje se."},{"v":13,"t":"Drvodjelja uzima mjeru, pisaljkom lik ocrta, ostruže ga dlijetom, šestarom ga zaokruži i izdjelja ga po uzoru na lik ljudski, kao lijepo ljudsko obličje, da stoji u hramu."},{"v":14,"t":"Bijaše sebi nasjekao cedre, uzeo čempres ili hrast koje je za se njegovao među šumskim drvećem; ili je posadio bor koji raste od kiše."},{"v":15,"t":"Čovjeku su dobra za vatru; uzima ih da se ogrije; pali ih da ispeče kruh. Ali od njih djelja i boga pred kojim pada ničice, pravi kip i klanja mu se."},{"v":16,"t":"Polovinom od toga naloži, dakle, oganj, peče meso na žeravi, jede pečenku i siti se: grije se i govori: “Ah, grijem se i uživam uz vatru.”"},{"v":17,"t":"Ali od onoga što preostane pravi sebi boga, svog kumira, pada pred njim ničice i klanja mu se i moli: “Spasi me, jer si ti moj bog.”"},{"v":18,"t":"Ne znaju oni i ne razumiju: zaslijepljene su im oči pa ne vide, i srce pa ne shvaćaju."},{"v":19,"t":"Takav ne razmišlja, nema u njega znanja ni razbora da sebi kaže: “Polovinom od ovoga naložio sam oganj, na žeravici ispekao kruh, ispržio meso koje sam pojeo, pa zar ću od ostatka načiniti gnusobu? Zar ću se komadu drveta klanjati?”"},{"v":20,"t":"On voli pepeo, zavodi ga prevareno srce. Neće spasti svog života i nikad neće reći: “Nije li varka ovo u mojoj desnici?”"},{"v":21,"t":"Sjeti se toga, Jakove, i ti, Izraele, jer si sluga moj! Ja sam te stvorio i sluga si mi, Izraele, neću te zaboraviti!"},{"v":22,"t":"Kao maglu rastjerao sam tvoje opačine i grijehe tvoje poput oblaka. Meni se obrati jer ja sam te otkupio."},{"v":23,"t":"Kličite, nebesa, jer je Jahve učinio! Orite se, dubine zemljine! Odjekujte radošću, planine, i vi, šume, sa svim svojim drvećem! Jer Jahve je otkupio Jakova, proslavio se u Izraelu!"},{"v":24,"t":"Ovako govori Jahve, otkupitelj tvoj i tvorac tvoj od utrobe: “Ja sam Jahve koji sam sve stvorio, koji sam nebesa sam razapeo i učvrstio zemlju bez pomoći ičije."},{"v":25,"t":"Ja osujećujem znamenja vrača, i čarobnjake u luđake promećem; silim mudrace da ustuknu i mudrost im obraćam u bezumlje,"},{"v":26,"t":"ali potvrđujem riječ sluge svojega, ispunjam naum svojih glasnika. Ja govorim Jeruzalemu: 'Naseli se!' I gradovima judejskim: 'Sagradite se!' Iz razvalina ja ih podižem."},{"v":27,"t":"Ja govorim moru: 'Presahni! Presušujem ti rijeke.'"},{"v":28,"t":"Ja govorim Kiru: 'Pastiru moj!' I on će sve želje moje ispuniti govoreći Jeruzalemu: 'Sagradi se!' i Hramu: 'Utemelji se!'”"}]},"45":{"hr":[{"v":1,"t":"Ovako govori Jahve o Kiru, pomazaniku svome: “Primih ga za desnicu da pred njim oborim narode i raspašem bokove kraljevima, da rastvorim pred njim vratnice, da mu nijedna vrata ne budu zatvorena."},{"v":2,"t":"Ja ću hoditi pred tobom da poravnam uzvisine, da razbijem mjedene vratnice, da slomim željezne prijevornice."},{"v":3,"t":"Dajem ti tajna blaga i skrivena bogatstva, da bi spoznao da sam ja Jahve koji te zovem po imenu, Bog Izraelov."},{"v":4,"t":"Radi sluge svog Jakova i Izraela, svog izabranika, po imenu ja te pozvah, imenovah te premda me znao nisi."},{"v":5,"t":"Ja sam Jahve i nema drugoga; osim mene Boga nema. Iako me ne poznaš, naoružah te:"},{"v":6,"t":"nek' se znade od istoka do zapada da izvan mene sve je ništavilo.” Ja sam Jahve i nema drugoga;"},{"v":7,"t":"ja tvorim svjetlost i stvaram tamu. Ja stvaram sreću i dovodim nesreću, ja, Jahve, činim sve to."},{"v":8,"t":"Rosite, nebesa, odozgo, i oblaci, daždite pravednošću. Neka se rastvori zemlja da procvjeta spasenje, da proklija izbavljenje! Ja, Jahve, stvaram sve."},{"v":9,"t":"Jao onome tko raspravlja s tvorcem svojim, a sud je među glinenim sudovima! Kaže li glina lončaru: “Što radiš?” ili djelo njegovo: “Kljast si!”"},{"v":10,"t":"Jao onom koji kaže ocu: “Što si rodio?” Ili ženi: “Što si na svijet dala?”"},{"v":11,"t":"Ovako govori Jahve, Svetac Izraelov, njegov tvorac: “Zar je vaše da me o mojoj djeci pitate i da mi nad djelom ruku mojih zapovijedate?"},{"v":12,"t":"Ja sam načinio zemlju i čovjeka na njoj stvorio; svojim sam rukama razapeo nebesa i zapovijedam svim vojskama njihovim."},{"v":13,"t":"Ja sam ga podigao da pobijedi i poravnao sam mu sve putove. On će obnoviti moj Grad i sužnje moje vratiti bez otkupnine i naknade.” Tako kaže Jahve nad Vojskama."},{"v":14,"t":"Ovako govori Jahve: “Ratari Egipta i trgovci Kuša, i Sebejci, ljudi rasta visoka, prijeći će tebi i tvoji će biti; za tobom će ići okovani, tebi će se klanjati i molit će ti se: 'Jedino je kod tebe Bog, nema drugoga; ništavni su bogovi.'”"},{"v":15,"t":"Doista ti si Bog skriveni, Bog Izraelov, Spasitelj."},{"v":16,"t":"Postidjet će se i poniknut će svi zajedno, otići će u ruglu oni koji prave kipove."},{"v":17,"t":"A Jahve će vječnim spasenjem spasit' Izraela. Nećete se postidjeti i nećete poniknuti dovijeka."},{"v":18,"t":"Da, ovako govori Jahve, nebesa Stvoritelj - on je Bog - koji je oblikovao i sazdao zemlju, koji ju je učvrstio i nije je stvorio pustu, već ju je uobličio za obitavanje: “Ja sam Jahve i nema drugoga."},{"v":19,"t":"Nisam govorio u tajnosti, u zakutku mračne zemlje. Nisam rekao potomstvu Jakovljevu: 'Tražite me u pustoši.' Ja, Jahve, govorim pravo i naviještam čestito.”"},{"v":20,"t":"“Saberite se i dođite, pristupite zajedno, svi preživjeli od naroda! Neznalice puke oni su što nose kip izrađen od drveta i mole boga koji ih spasit' ne može."},{"v":21,"t":"Objavite, iznesite svoje dokaze, svjetujte se zajedno: tko je to od davnine navijestio i od tada prorekao? Nisam li ja, Jahve? Nema drugoga boga do mene; Boga pravednog i Spasitelja osim mene nema."},{"v":22,"t":"Obratite se k meni da se spasite, svi krajevi zemlje, jer ja sam Bog i nema drugoga!"},{"v":23,"t":"Sobom se samim kunem, iz mojih usta izlazi istina, riječ neopoziva, da će se preda mnom prignuti svako koljeno, mnome će se svaki jezik zaklinjati"},{"v":24,"t":"govoreći: 'Jedino je u Jahvi pobjeda i snaga!'” K njemu će doći, postiđeni, svi što na nj su bjesnjeli."},{"v":25,"t":"U Jahvi će pobijediti i proslavit se sve potomstvo Izraelovo!"}]},"46":{"hr":[{"v":1,"t":"Pade Bel! Sruši se Nebo! Prte svoje kipove na životinje i stoku, nose ih kao breme, teret što zamara."},{"v":2,"t":"Padaju, ruše se svi zajedno, ne mogu spasiti one što ih nose, nego i sami u ropstvo odlaze."},{"v":3,"t":"“Slušajte me, kućo Jakovljeva, i svi koji ostadoste od kuće Izraelove! Ja sam vas ponio tek što se rodiste, i nosio vas od krila materina."},{"v":4,"t":"Do starosti vaše ja ću ostat' isti, do vaših sjedina podupirat ću vas. To sam činio; nosit ću vas i dalje, pomagati vas, izbavljati."},{"v":5,"t":"S kime biste me usporedili i izjednačili, s kime prispodobili: komu da sam sličan?"},{"v":6,"t":"Vade zlato iz kese i tezuljom mjere srebro, pa naimlju zlatara da od njeg boga načini te pred njim padaju ničice i klanjaju se."},{"v":7,"t":"Dižu ga na rame i nose ga, onda ga stavljaju na njegovo mjesto; on stoji i ne miče se s njega. Prizivaju li ga, on ne odgovara i nikog ne spasava od nevolje njegove."},{"v":8,"t":"Sjetite se toga i budite ljudi, uzmite to k srcu, otpadnici,"},{"v":9,"t":"sjetite se prošlosti pradavne: ja sam Bog i nema drugoga; Bog, nitko mi sličan nije!"},{"v":10,"t":"Onaj sam koji od početka svršetak otkriva i unaprijed javlja što još se nije zbilo! Ja kažem: Odluka će se moja ispuniti, izvršit ću sve što mi je po volji."},{"v":11,"t":"S istoka zovem grabljivicu, iz daleke zemlje zovem čovjeka svog nauma. Rekao sam - ispunit ću, naumio sam - izvršit ću."},{"v":12,"t":"Slušajte me, vi koji gubite srčanost i koji ste daleko od pobjede."},{"v":13,"t":"Primičem svoju pobjedu, nije više daleko, spasenje moje zakasniti neće. Na Sion ću spas staviti, u Izraela svoju slavu.”"}]},"47":{"hr":[{"v":1,"t":"Spusti se, sjedni u prašinu, djevice, kćeri babilonska! Sjedni na zemlju, bez prijestolja, kćeri kaldejska! Jer, neće te više zvati nježnom i tankoćutnom."},{"v":2,"t":"Uzmi mlin i melji brašno! Skini prijevjes, podigni skut, razgali bedra, prijeđi preko rijeke!"},{"v":3,"t":"Nek' se golotinja tvoja otkrije, nek' se sramota tvoja pokaže! Ja ću se osvetiti, odvraćat' me nitko neće."},{"v":4,"t":"Otkupitelj naš, ime mu je Jahve nad Vojskama, Svetac Izraelov, kaže:"},{"v":5,"t":"“Sjedi šutke, u mrak se povuci, kćeri kaldejska. Jer, neće te više zvati vladaricom kraljevstava."},{"v":6,"t":"Razgnjevih se na svoj narod, oskvrnuh svoju baštinu. Tebi ih u ruke izručih, a ti im ne iskaza milosti. Na starce si stavljala jaram svoj preteški."},{"v":7,"t":"Govorila si: 'Dovijeka gospodaricom ću ostati.' Nikad nisi to k srcu uzela ni pomislila kako će se završiti."},{"v":8,"t":"A sad poslušaj, razvratnice, koja sjediš bezbrižno i u srcu svom govoriš: 'Ja, i nitko drugi! Nikad neću obudovjeti, neću djece izgubiti!'"},{"v":9,"t":"Stići će te oboje, za tren, u isti dan! Izgubit ćeš djecu, obudovjet ćeš! Punom će te mjerom snaći oboje, pokraj svega tvojeg vračanja i množine tvojih zaklinjanja!"},{"v":10,"t":"U zloću si se svoju uzdala, govorila si: 'Nitko me ne vidi!' Mudrost tvoja i znanje zavedoše te. U svom si srcu govorila: 'Ja i nitko drugi!'"},{"v":11,"t":"Zlo će te snaći - nećeš ga presresti; oborit će se na te nesreća - nećeš je odvratiti; doći će na te propast iznenada - nećeš je predvidjeti."},{"v":12,"t":"Ustraj, dakle, u svojim zaklinjanjima i u tolikim svojim čaranjima, oko kojih si se trudila od mladosti. Možda će ti biti od koristi? Možda ćeš s njima strah utjerati?"},{"v":13,"t":"Izmoriše te mnogi tvoji savjetnici! Nek' ustanu samo da te spase oni koji premjeravaju nebesa, koji promatraju zvijezde i koji svakog mjeseca proriču ono što će te snaći."},{"v":14,"t":"Gle, oni će biti poput pljeve, oganj će ih sažeći. Ni sami sebe neće izbaviti iz zagrljaja plamenoga. Neće ostat' ni žerave da se tko ogrije, ni ognjišta da uza nj posjedne!"},{"v":15,"t":"Takvi će ti biti vrači tvoji, oko kojih si se trudila od mladosti! Poći će svaki svojim putem, i nikog neće biti da te spasi.”"}]},"48":{"hr":[{"v":1,"t":"Čujte ovo, kućo Jakovljeva, vi koji se zovete imenom Izraelovim i koji ste izišli iz voda Judinih! Vi koji se Jahvinim imenom kunete i slavite Boga Izraelova, ali ne u istini i pravdi."},{"v":2,"t":"Jer vi se nazivate po Svetome gradu i oslanjate se na Boga Izraelova, Jahve nad Vojskama njemu je ime."},{"v":3,"t":"Dogođaje prošle odavna sam navijestio, iz mojih su izišli usta i ja sam ih objavio, učinih brzo, i zbi se."},{"v":4,"t":"Jer znao sam da si tvrdokoran, da ti je šija žila gvozdena i čelo da ti je mjedeno."},{"v":5,"t":"Zato sam ti već onda navijestio, javio ti prije nego što se zbilo, da ne bi rekao: “Moj kip učini to, rezani moj lik i ljeveni kip zapovjediše tako!”"},{"v":6,"t":"Čuo si i vidio sve to; zar ne priznaješ? A sada navijestit ću ti nešto novo, otajno, što još ne znaš;"},{"v":7,"t":"ovog je trena stvoreno, a ne odavna, o tome dosad nisi ništa čuo, da ne bi rekao: “Znao sam.”"},{"v":8,"t":"Nisi o tome čuo ni znao, niti se uho tvoje prije otvorilo, jer znadoh da ćeš se iznevjeriti i da te od utrobe majčine zovu otpadnikom."},{"v":9,"t":"Radi imena svoga odgađah svoj gnjev, radi časti svoje susprezah se da te ne uništim."},{"v":10,"t":"Gle, pročistio sam te poput srebra, iskušao te u talioniku nevolje."},{"v":11,"t":"Sebe radi činih tako, sebe radi! TÓa zar da se ime moje obeščasti? Slave svoje drugome ne dam!"},{"v":12,"t":"Čuj me, Jakove, Izraele, koga sam pozvao: Ja jesam, ja sam prvi, ja sam i posljednji."},{"v":13,"t":"Ruka moja zemlju utemelji, desnica mi razape nebesa. Pozovem ih samo, i odmah dolaze."},{"v":14,"t":"Saberite se svi i čujte: tko je od njih to prorekao? “Onaj koga Jahve ljubi ispunit će volju moju nad Babilonom i nad potomstvom kaldejskim.”"},{"v":15,"t":"Ja rekoh i pozvah ga, vodih ga i pomogoh u naumu."},{"v":16,"t":"Pristupite k meni i počujte ovo: “Od početka nisam vam govorio tajno, i kad se zbivalo, bijah ondje.” - “A sada me Gospod Jahve šalje s duhom svojim.”"},{"v":17,"t":"Ovako govori Jahve, otkupitelj tvoj, Svetac Izraelov: “Ja, Jahve, Bog tvoj, tvojem dobru te učim, vodim te putem kojim ti je ići."},{"v":18,"t":"O, da si pazio na zapovijedi moje, kao rijeka sreća bi tvoja bila, a pravda tvoja kao morski valovi!"},{"v":19,"t":"Potomstva bi tvojeg bilo kao pijeska, a poroda utrobe tvoje kao njegovih zrnaca! Nikad ti se ime ne bi zatrlo niti izbrisalo preda mnom!”"},{"v":20,"t":"Izađite iz Babilona, bježite iz Kaldeje! Glasno kličući, kazujte, objavljujte, do nakraj zemlje razglasite! Govorite: “Jahve je otkupio slugu svoga Jakova!"},{"v":21,"t":"Nisu žeđali dok ih je kroz pustinju vodio; iz stijene je za njih vodu izbio, rascijepio je pećinu i potekla je voda.”"},{"v":22,"t":"“Nema mira opakima,” kaže Jahve."}]},"49":{"hr":[{"v":1,"t":"Čujte me, otoci, slušajte pomno, narodi daleki! Jahve me pozvao od krila materina, od utrobe majke moje spomenuo se moga imena."},{"v":2,"t":"Od usta mojih britak mač je načinio, sakrio me u sjeni ruke svoje, od mene je oštru načinio strijelu, sakrio me u svome tobolcu."},{"v":3,"t":"Rekao mi: “Ti si Sluga moj, Izraele, u kom ću se proslaviti!”"},{"v":4,"t":"A ja rekoh: “Zaludu sam se mučio, nizašto naprezao snagu.” Ipak, kod Jahve je moje pravo, kod mog Boga nagrada je moja. A sad govori Jahve, koji me od utrobe Slugom svojim načini, da mu vratim natrag Jakova, da se sabere Izrael."},{"v":5,"t":"Proslavih se u očima Jahvinim, Bog moj bijaše mi snaga."},{"v":6,"t":"I reče mi: “Premalo je da mi budeš Sluga, da podigneš plemena Jakovljeva i vratiš Ostatak Izraelov, nego ću te postaviti za svjetlost narodima, da spas moj do nakraj zemlje doneseš.”"},{"v":7,"t":"Ovako govori Jahve, otkupitelj Izraelov, Svetac njegov, onome kog preziru i odbacuju narodi, sluzi silničkome: “Kad vide, dići će se kraljevi, bacit će se ničice knezovi, zbog Jahve, koji je vjernost svoju pokazao, Sveca Izraelova, koji te izabrao.”"},{"v":8,"t":"Ovako govori Jahve: “U vrijeme milosti ja ću te uslišiti, u dan spasa ja ću ti pomoći. Sazdao sam te i postavio za Savez narodu, da zemlju podignem, da nanovo razdijelim baštinu opustošenu,"},{"v":9,"t":"da kažeš zasužnjenima: 'Iziđite!' a onima koji su u tami: 'Dođite na svjetlo!' Oni će pasti uzduž svih putova, i paša će im biti po svim goletima."},{"v":10,"t":"Neće više gladovat' i žeđati, neće ih mučiti žega ni sunce, jer vodit će ih onaj koji im se smiluje, dovest će ih k izvorima vode."},{"v":11,"t":"Sve gore svoje obratit će u putove, i ceste će se moje povisiti.”"},{"v":12,"t":"Gle, jedni dolaze izdaleka, drugi sa sjevera i sa zapada, a neki iz zemlje sinimske."},{"v":13,"t":"Kličite, nebesa, veseli se, zemljo, podvikujte, planine, od veselja; jer Jahve tješi narod svoj, on je milosrdan nevoljnima."},{"v":14,"t":"Sion reče: “Jahve me ostavi, Gospod me zaboravi.”"},{"v":15,"t":"“Može li žena zaboravit' svoje dojenče, ne imat' sućuti za čedo utrobe svoje? Pa kad bi koja i zaboravila, tebe ja zaboraviti neću."},{"v":16,"t":"Gle, u dlanove sam te svoje urezao, zidovi tvoji svagda su mi pred očima."},{"v":17,"t":"Obnovitelji tvoji hitaju, rušioci tvoji i pustošitelji odlaze od tebe."},{"v":18,"t":"Obazri se oko sebe i pogledaj: sabiru se svi i dolaze k tebi. Života mi moga” - riječ je Jahvina - “svima ćeš se njima zaodjenuti k'o nakitom, i njima ćeš se k'o nevjesta ukrasiti!"},{"v":19,"t":"Jest, tvoje ruševine, tvoje razvaline i tvoja zemlja poharana pretijesna će biti žiteljima tvojim kad se udalje oni što te zatirahu."},{"v":20,"t":"Opet će na tvoje uši reći sinovi kojih si bila lišena: 'Pretijesno mi je mjesto ovo, makni se da se mogu smjestiti.'"},{"v":21,"t":"I ti ćeš se u srcu svom zapitati: 'Tko mi rodi sve ove? Bijah bez djece, neplodna, prognana i odbačena, pa tko ih podiže? Bijah, eto, sama ostala, a oni gdje su bili?'”"},{"v":22,"t":"Ovako govori Gospod Jahve: “Evo, dajem rukom znak narodima i zastavu svoju dižem plemenima. Vratit će ti u naručju sinove, nosit će ti kćeri na plećima."},{"v":23,"t":"Kraljevi će biti tvoji skrbnici, a kneginje im tvoje dojkinje. Klanjat će ti se licem do zemlje i prah će lizat s tvojih nogu. I znat ćeš da sam ja Jahve: koji se u me uzdaju, neće se posramiti.”"},{"v":24,"t":"Može li se otet plijen junaku? Može li sužanj pobjeć pobjedniku?"},{"v":25,"t":"Da, ovako govori Jahve: “Bit će oduzet sužanj junaku, pobjeći će plijen pobjedniku! S onima koji se s tobom spore ja ću se sporiti, tvoju djecu ja ću izbaviti;"},{"v":26,"t":"tlačiteljima ću tvojim dati njihovo meso za jelo i svojom krvlju opit će se kao moštom. I znat će svako tijelo da sam ja Jahve, Spasitelj tvoj, i da je tvoj okupitelj Silni Jakovljev.”"}]},"50":{"hr":[{"v":1,"t":"Ovako govori Jahve: “Gdje je otpusno pismo vaše matere kojim sam je otpustio? Ili tko je od mojih vjerovnika taj komu sam vas prodao? Zbog bezakonja ste svojih prodani, zbog nevjere je mati vaša otpuštena."},{"v":2,"t":"Zašto ne nađoh nikoga kad sam došao? Zašto se ne odazva nitko kad sam zazvao? Zar mi je ruka prekratka da izbavi, ili u meni snage nema da oslobodim? Gle, prijetnjom svojom isušujem more, u pustinje rijeke pretvaram; njihove se ribe raspadaju jer vode nema i od žeđi ugibaju."},{"v":3,"t":"Nebesa oblačim u tminu i kostrijet im dajem za pokrivač!”"},{"v":4,"t":"Gospod Jahve dade mi jezik vješt da znam riječju krijepiti umorne. Svako jutro on mi uho budi da ga slušam kao učenici."},{"v":5,"t":"Gospod Jahve uši mi otvori: ne protivih se niti uzmicah."},{"v":6,"t":"Leđa podmetnuh onima što me udarahu, a obraze onima što mi bradu čupahu, i lica svojeg ne zaklonih od uvreda ni od pljuvanja."},{"v":7,"t":"Gospod mi Jahve pomaže, zato se neću smesti. Zato učinih svoj obraz k'o kremen i znam da se neću postidjeti."},{"v":8,"t":"Blizu je onaj koji mi pravo daje. Tko će se pravdati sa mnom? Iziđimo zajedno! Tko je protivnik moj u parnici? Nek' mi se približi!"},{"v":9,"t":"Gle, Gospod mi Jahve pomaže, tko će me osuditi? Svi će se oni k'o haljina izlizati, moljac će ih razjesti."},{"v":10,"t":"“Tko god se od vas Jahve boji, nek' posluša glas Sluge njegova! Tko u tmini hodi, bez tračka svjetlosti, nek' se uzda u ime Jahvino, nek' se na Boga svog osloni."},{"v":11,"t":"Ali svi vi oganj palite, raspirujete žeravicu. Idite u plamenove ognja svojega i u žeravu koju raspiriste. Tako će vam moja učiniti ruka: ležat ćete u mukama."}]},"51":{"hr":[{"v":1,"t":"Čujte me, vi koji za pravdom težite, koji Jahvu tražite; pogledajte stijenu iz koje ste isječeni i jamu duboku iz koje ste izvađeni."},{"v":2,"t":"Pogledajte oca svoga Abrahama i Saru koja vas porodi! Jest, sam bijaše kad sam ga pozvao, al' sam ga blagoslovio i umnožio.”"},{"v":3,"t":"Jest, Jahvi se sažalio Sion, sažalile mu se njegove razvaline. Pustaru će njegovu učiniti poput Edena, a stepu poput Vrta Jahvina. Klicanje i radost njim će odjekivat', i zahvalnice i glas hvalospjeva."},{"v":4,"t":"“Pomno me slušaj, puče moj, počujte me, narodi! Jer od mene Zakon dolazi i moje pravo za svjetlo narodima."},{"v":5,"t":"Brzo će stići pravda moja, moje će spasenje doći kao svjetlost. Moja će mišica suditi narodima. Mene očekuju otoci i u moju se mišicu uzdaju."},{"v":6,"t":"K nebu oči podignite, na zemlju dolje pogledajte. K'o dim će se rasplinut' nebesa, zemlja će se k'o haljina istrošit', kao komarci nestat će joj žitelji. Ali će spasenje moje trajati dovijeka, i pravdi mojoj neće biti kraja."},{"v":7,"t":"Poslušajte me, vi koji poznajete pravo, narode kojima je moj Zakon u srcu. Ne bojte se poruge ljudske, ne plašite se uvreda!"},{"v":8,"t":"Jer moljac će ih razjesti kao haljinu, crv će ih rastočiti kao vunu. Ali će pravda moja trajati dovijeka i spas moj od koljena do koljena.”"},{"v":9,"t":"Probudi se! Probudi se! Opaši se snagom, mišice Jahvina! Probudi se, kao u dane davne, za drevnih naraštaja. Nisi li ti rasjekla Rahaba i probola Zmaja?"},{"v":10,"t":"Nisi li ti isušila more, vodu velikog bezdana, i od dubine morske put načinila da njime prolaze otkupljeni?"},{"v":11,"t":"Vratit će se oni što ih je oslobodio Jahve i s radosnim kricima doći će na Sion. Vječna će sreća biti nad glavama, pratit će ih klicanje i radost, nestat će tuge i jecaja."},{"v":12,"t":"Ja, ja sam tješitelj vaš. Tko si ti da se bojiš smrtna čovjeka i sina čovječjeg, koji je kao trava?"},{"v":13,"t":"Zaboravio si Jahvu, svoga Stvoritelja, koji razastrije nebesa i koji zemlju utemelji; sveudilj strepiš, svaki dan, od tlačiteljeve jarosti. Kao da je pregnuo da te uništi. Ali gdje je sad jarost tlačiteljeva?"},{"v":14,"t":"Doskora će biti slobodan sužanj, neće umrijeti u jami, niti će mu kruha nedostajati."},{"v":15,"t":"Jer, ja sam Jahve, Bog tvoj, koji burkam more da mu valovi buče, ime mi je Jahve nad Vojskama."},{"v":16,"t":"Svoje sam ti riječi stavio u usta, u sjenu svoje ruke sakrio sam te kad sam razastro nebesa, utemeljio zemlju i rekao Sionu: “Ti si narod moj!”"},{"v":17,"t":"Probudi se, probudi se, ustani, Jeruzaleme! Ti koji si pio iz ruke Jahvine čašu gnjeva njegova. Ispio si pehar opojni, do dna ga iskapio."},{"v":18,"t":"Od svih sinova koje je rodio ne bješe nikog da ga vodi; od svih sinova koje je podigao ne bješe nikog da ga pridrži."},{"v":19,"t":"Ovo te dvoje pogodilo - tko da te požali? - pohara i rasap, glad i mač - tko da te utješi?"},{"v":20,"t":"Sinovi ti leže obamrli po uglovima svih ulica, kao antilopa u mreži, puni gnjeva Jahvina, prijetnje Boga tvojega."},{"v":21,"t":"Zato čuj ovo, bijedniče, pijan, ali ne od vina."},{"v":22,"t":"Ovako govori Jahve, Gospod tvoj, tvoj Bog, branitelj tvoga naroda: “Iz ruke ti, evo, uzimam čašu opojnu, pehar gnjeva svojega: nećeš ga više piti."},{"v":23,"t":"Stavit ću je u ruke tvojim tlačiteljima, onima koji su ti govorili: 'Prigni se da prijeđemo!' I ti si im leđa kao tlo podmetao, kao put za prolaznike."}]},"52":{"hr":[{"v":1,"t":"Probudi se! Probudi se! Odjeni se snagom, Sione! Odjeni se najsjajnijim haljinama, Jeruzaleme, grade sveti, jer više neće k tebi ulaziti neobrezani i nečisti."},{"v":2,"t":"Otresi prah sa sebe, ustani, izgnani Jeruzaleme! Skini okov sa svog vrata, izgnana kćeri sionska.”"},{"v":3,"t":"Jest, ovako govori Jahve: “Bili ste prodani nizašto i bit ćete otkupljeni bez novaca.”"},{"v":4,"t":"Jest, ovako govori Gospod Jahve: “Moj je narod sišao nekoć u Egipat da se ondje nastani kao stranac, potom ga Asirci nizašto potlačiše."},{"v":5,"t":"Ali sada, čemu sam ja ovdje - riječ je Jahvina - kad je moj narod bio bez razloga porobljen, a gospodari njegovi likuju - riječ je Jahvina - i bez prestanka se danomice ime moje huli."},{"v":6,"t":"Zato će narod moj poznati moje ime i shvatit će u onaj dan da sam ja koji govorim: 'Evo me!'”"},{"v":7,"t":"Kako su ljupke po gorama noge glasonoše radosti koji oglašava mir, nosi sreću, i spasenje naviješta govoreć Sionu: “Bog tvoj kraljuje!”"},{"v":8,"t":"Čuj, stražari ti glas podižu, zajedno svi kliču od radosti, jer na svoje oči vide gdje se na Sion vraća Jahve."},{"v":9,"t":"Radujte se, kličite, razvaline jeruzalemske, jer je Jahve utješio narod svoj i otkupio Jeruzalem."},{"v":10,"t":"Ogolio je Jahve svetu svoju mišicu pred očima svih naroda, da svi krajevi zemaljski vide spasenje Boga našega."},{"v":11,"t":"Odlazite, odlazite, iziđite odatle, ne dotičite ništa nečisto! Iziđite iz njegove sredine! Očistite se, vi koji nosite posude Jahvine!"},{"v":12,"t":"Jer nećete izići u hitnji, niti ćete ići bježeći, jer će vam prethodnica biti Jahve, a zalaznica Bog Izraelov!"},{"v":13,"t":"Gle, uspjet će Sluga moj, podignut će se, uzvisit' i proslaviti!"},{"v":14,"t":"Kao što se mnogi užasnuše vidjevši ga - tako mu je lice bilo neljudski iznakaženo te obličjem više nije naličio na čovjeka -"},{"v":15,"t":"tako će on mnoge zadiviti narode i kraljevi će pred njim usta stisnuti videć' ono o čemu im nitko nije govorio, shvaćajuć' ono o čemu nikad čuli nisu:"}]},"53":{"hr":[{"v":1,"t":"“Tko da povjeruje u ono što nam je objavljeno, kome se otkri ruka Jahvina?”"},{"v":2,"t":"Izrastao je pred njim poput izdanka, poput korijena iz zemlje sasušene. Ne bijaše na njem ljepote ni sjaja da bismo se u nj zagledali, ni ljupkosti da bi nam se svidio."},{"v":3,"t":"Prezren bješe, odbačen od ljudi, čovjek boli, vičan patnjama, od kog svatko lice otklanja, prezren bješe, odvrgnut."},{"v":4,"t":"A on je naše bolesti ponio, naše je boli na se uzeo, dok smo mi držali da ga Bog bije i ponižava."},{"v":5,"t":"Za naše grijehe probodoše njega, za opačine naše njega satriješe. Na njega pade kazna - radi našeg mira, njegove nas rane iscijeliše."},{"v":6,"t":"Poput ovaca svi smo lutali i svaki svojim putem je hodio. A Jahve je svalio na nj bezakonje nas sviju."},{"v":7,"t":"Zlostavljahu ga, a on puštaše, i nije otvorio usta svojih. K'o jagnje na klanje odvedoše ga; k'o ovca, nijema pred onima što je strižu, nije otvorio usta svojih."},{"v":8,"t":"Silom ga se i sudom riješiše; tko se brine za njegovu sudbinu? Da, iz zemlje živih ukloniše njega, za grijehe naroda njegova nasmrt ga izbiše."},{"v":9,"t":"Ukop mu odrediše među zločincima, a grob njegov bi s bogatima, premda nije počinio nepravde nit' su mu usta laži izustila."},{"v":10,"t":"Al' se Jahvi svidje da ga pritisne bolima. Žrtvuje li život svoj za naknadnicu, vidjet će potomstvo, produžit' sebi dane i Jahvina će se volja po njemu ispuniti."},{"v":11,"t":"Zbog patnje duše svoje vidjet će svjetlost i nasititi se spoznajom njezinom. Sluga moj pravedni opravdat će mnoge i krivicu njihovu na sebe uzeti."},{"v":12,"t":"Zato ću mu mnoštvo dati u baštinu i s mogućnicima plijen će dijeliti, jer sam se ponudio na smrt i među zlikovce bio ubrojen, da grijehe mnogih ponese na sebi i da se zauzme za zločince."}]},"54":{"hr":[{"v":1,"t":"Kliči, nerotkinjo, koja nisi rađala; podvikuj od radosti, ti što ne znaš za trudove! Jer osamljena više djece ima negoli udata, kaže Jahve."},{"v":2,"t":"Raširi prostor svog šatora, razastri, ne štedi platna svog prebivališta, produži mu užeta, kolčiće učvrsti!"},{"v":3,"t":"Jer proširit ćeš se desno i lijevo. Tvoje će potomstvo zavladat' narodima i napučit će opustjele gradove."},{"v":4,"t":"Ne boj se, nećeš se postidjeti; na srami se, nećeš se crvenjeti. Zaboravit ćeš sramotu svoje mladosti i više se nećeš spominjati rugla udovištva svoga."},{"v":5,"t":"Jer suprug ti je tvoj Stvoritelj, ime mu je Jahve nad Vojskama; tvoj je Otkupitelj Svetac Izraelov, Bog zemlje svekolike on se zove."},{"v":6,"t":"Jest, k'o ženu ostavljenu, u duši ucviljenu, Jahve te pozvao. Zar se smije otpustiti žena svoje mladosti, pita Bog tvoj."},{"v":7,"t":"“Za kratak trenutak ostavih tebe, al' u sućuti velikoj opet ću te prigrliti."},{"v":8,"t":"U provali srdžbe sakrih načas od tebe lice svoje, al' u ljubavi vječnoj smilovah se tebi,” govori Jahve, tvoj Otkupitelj."},{"v":9,"t":"“Bit će mi k'o za Noinih dana, kad se zakleh da vode Noine neće više preplaviti zemlju; tako se zaklinjem da se više neću na tebe srditi nit' ću ti prijetiti."},{"v":10,"t":"Nek' se pokrenu planine i potresu brijezi, al' se ljubav moja neće odmać' od tebe, nit' će se pokolebati moj Savez mira,” kaže Jahve koji ti se smilovao."},{"v":11,"t":"“O nevoljnice, vihorom vitlana, neutješna, gle, postavit ću na smaragd tvoje kamenje i na safir tvoje temelje."},{"v":12,"t":"Od rubina dići ću ti kruništa, vrata tvoja od prozirca, ograde ti od dragulja."},{"v":13,"t":"Svi će ti sinovi Jahvini biti učenici, i velika će biti sreća djece tvoje."},{"v":14,"t":"Na pravdi ćeš biti zasnovana. Odbaci tjeskobu, nemaš se čega bojati, odbaci strah jer ti se neće primaći."},{"v":15,"t":"Ako li te napadnu, neće doći od mene; tko se na te digne, zbog tebe će pasti."},{"v":16,"t":"Gle, ja sam stvorio kovača koji raspaljuje žeravu i vadi iz nje oružje da ga kuje. Ali stvorih i zatornika da uništava."},{"v":17,"t":"Neće uspjeti oružje protiv tebe skovano. Dokazat ćeš da je zao svaki jezik što na te udari na sudu. To je baština slugu Jahvinih, to im je pobjeda od mene” - riječ je Jahvina."}]},"55":{"hr":[{"v":1,"t":"“O svi vi koji ste žedni, dođite na vodu; ako novaca i nemate, dođite. Bez novaca i bez naplate kupite vina i mlijeka!"},{"v":2,"t":"Zašto da trošite novac na ono što kruh nije i nadnicu svoju na ono što ne siti? Mene poslušajte, i dobro ćete jesti i sočna ćete uživati jela."},{"v":3,"t":"Priklonite uho i k meni dođite, poslušajte, i duša će vam živjeti. Sklopit ću s vama Savez vječan, Savez milosti Davidu obećanih.”"},{"v":4,"t":"Evo, učinih te svjedokom pucima, knezom i zapovjednikom narodima."},{"v":5,"t":"Evo, pozvat ćeš narod koji ne poznaješ, i narod koji te ne zna dohrlit će k tebi radi Jahve, Boga tvojega, i Sveca Izraelova, jer on te proslavio."},{"v":6,"t":"Tražite Jahvu dok se može naći, zovite ga dok je blizu!"},{"v":7,"t":"Nek' bezbožnik put svoj ostavi, a zlikovac naume svoje. Nek' se vrati Gospodu, koji će mu se smilovati, k Bogu našem jer je velikodušan u praštanju."},{"v":8,"t":"“Jer misli vaše nisu moje misli i puti moji nisu vaši puti,” riječ je Jahvina."},{"v":9,"t":"“Visoko je iznad zemlje nebo, tako su puti moji iznad vaših putova, i misli moje iznad vaših misli.”"},{"v":10,"t":"“Kao što daždi i sniježi s neba bez prestanka dok se zemlja ne natopi, oplodi i ozeleni da bi dala sjeme sijaču i kruha za jelo,"},{"v":11,"t":"tako se riječ koja iz mojih usta izlazi ne vraća k meni bez ploda, nego čini ono što sam htio i obistinjuje ono zbog čega je poslah.”"},{"v":12,"t":"Da, s radošću ćete otići i u miru ćete biti vođeni. Gore će i brda klicati od radosti pred vama i sva će stabla u polju pljeskati."},{"v":13,"t":"Umjesto trnja rast će čempresi, umjesto koprive mirta će nicati. I bit će to Jahvi na slavu, kao znak vječan, neprolazan."}]},"56":{"hr":[{"v":1,"t":"Ovako govori Jahve: “Držite se prava i činite pravdu, jer će uskoro doći moj spas i objaviti se moja pravednost.”"},{"v":2,"t":"Blago čovjeku koji čini tako i sinu čovječjem što se toga pridržava: koji poštuje subotu da je ne oskvrni i koji ruke svoje čuva od svakoga zla djela."},{"v":3,"t":"Neka sin tuđinčev koji je prionuo uz Jahvu ne govori: “Jamačno će me Jahve odvojiti od svojega naroda.” Neka uškopljenik ne govori: “Ja sam, evo, tek suho drvo.”"},{"v":4,"t":"Jer ovako govori Jahve: “S uškopljenicima koji obdržavaju subotu, koji izabiru što je meni drago i ostanu postojani u Savezu mome -"},{"v":5,"t":"podići ću u kući svojoj i među svojim zidovima spomenik i ime, bolje nego sinovima i kćerima, dat ću im vječno ime koje neće biti iskorijenjeno."},{"v":6,"t":"A sinove tuđinske koji pristadoše uz Jahvu da mu služe i da ljube ime Jahvino i da mu budu službenici, koji poštuju subotu i ne oskvrnjuju je i postojani su u Savezu mome,"},{"v":7,"t":"njih ću dovesti na svoju svetu goru i razveseliti u svojem Domu molitve. Njihove žrtve paljenice i klanice bit će ugodne na mojem žrtveniku, jer će se Dom moj zvati Dom molitve za sve narode.”"},{"v":8,"t":"Riječ je Gospoda Jahve koji sabire raspršene Izraelce: “Sabrat ću ih još povrh onih koji su već sabrani.”"},{"v":9,"t":"Sve zvijeri poljske, dođite jesti, i sve vi, zvijeri šumske!"},{"v":10,"t":"Svi su mu stražari slijepi, i ništa ne shvaćaju. Svi su oni psi nijemi, ne mogu lajati. Sanjaju i drijemlju, najmilije im spavati."},{"v":11,"t":"Psi su to proždrljivi, nezasitni; pastiri su to bez razbora: svaki svojim putem okreće, svaki za dobitkom svojim."},{"v":12,"t":"“Dođite, donijet ću vina; napit ćemo se pića žestoka, i sutra će biti kao danas, izobilje veliko, preveliko!”"}]},"57":{"hr":[{"v":1,"t":"Pravednik gine, i nitko ne mari. Uklanjaju ljude pobožne, i nitko ne shvaća. Da, zbog zla uklonjen je pravednik"},{"v":2,"t":"da bi ušao u mir. Tko god je pravim putem hodio počiva na svom ležaju."},{"v":3,"t":"Pristupite sad, sinovi vračarini, leglo preljubničko i bludničko!"},{"v":4,"t":"S kim se podrugujete, na koga razvaljujete usta i komu jezik plazite? Niste li vi porod grešan i leglo lažljivo?"},{"v":5,"t":"Vi koji se raspaljujete među hrašćem, pod svakim zelenim drvetom, žrtvujući djecu u dolinama i u rasjelinama stijena!"},{"v":6,"t":"Dio je tvoj među oblucima potočnim, oni, oni su baština tvoja. Njima izlijevaš ljevanicu, njima prinosiš darove! Zar da se time ja utješim?"},{"v":7,"t":"Na gori visokoj, uzdignutoj, svoj si ležaj postavila i popela se onamo da prinosiš žrtvu klanicu."},{"v":8,"t":"Za vrata i dovratke metnula si spomen svoj; daleko od mene svoj ležaj raskrivaš, penješ se na nj i širiš ga. Pogađala si se s onima s kojima si voljela lijegati, sve si više bludničila s njima gledajuć' im mušku snagu."},{"v":9,"t":"S uljem za Molekom trčiš, s pomastima mnogim, nadaleko posla glasnike svoje, strovali ih u Podzemlje."},{"v":10,"t":"Iscrpljena si od tolikih lutanja, al' nisi rekla: “Beznadno je!” Snagu si svoju nanovo našla te nisi sustala."},{"v":11,"t":"Koga si se uplašila i pobojala da si se iznevjerila, da se više nisi mene spominjala, niti si me k srcu uzimala? Šutio sam, zatvarao oči, zato me se nisi bojala."},{"v":12,"t":"Ali ću objavit' o tvojoj pravdi i djela ti tvoja neće koristiti."},{"v":13,"t":"Kad uzmeš vikati, nek' te izbave kipovi koje si skupila, sve će ih vjetar raznijeti, vihor će ih otpuhnuti. A tko se u me uzda, baštinit će zemlju i zaposjest će svetu goru moju."},{"v":14,"t":"Govorit će se: Naspite, naspite, poravnajte put! Uklonite zapreke s puta mog naroda!"},{"v":15,"t":"Jer ovako govori Višnji i Uzvišeni, koji vječno stoluje i ime mu je Sveti: “U prebivalištu visokom i svetom stolujem, ali ja sam i s potlačenim i poniženim, da oživim duh smjernih, da oživim srca skrušenih."},{"v":16,"t":"Jer neću se prepirati dovijeka ni vječno se ljutiti: preda mnom bi podlegao duh i duše što sam ih stvorio."},{"v":17,"t":"Zbog grijeha lakomosti njegove razgnjevih se, udarih ga i sakrih se rasrđen. Ali on okrenu za srcem svojim"},{"v":18,"t":"i vidjeh putove njegove. Izliječit ću ga, voditi i utješit' one što s njime tuguju -"},{"v":19,"t":"stavit ću hvalu na usne njihove. Mir, mir onom tko je daleko i tko je blizu,” govori Jahve, “ja ću te izliječiti.”"},{"v":20,"t":"Al' opaki su poput mora uzburkanog koje se ne može smiriti, valovi mu mulj i blato izmeću."},{"v":21,"t":"“Nema mira grešnicima!” govori Bog moj."}]},"58":{"hr":[{"v":1,"t":"Viči iz sveg grla, ne suspeži se! Glas svoj poput roga podigni. Objavi mom narodu njegove zločine, domu Jakovljevu grijehe njegove."},{"v":2,"t":"Dan za danom oni mene traže i žele znati moje putove, kao narod koji vrši pravdu i ne zaboravlja pravo Boga svoga. Od mene ištu pravedne sudove i žude da im se Bog približi:"},{"v":3,"t":"“Zašto postimo ako ti ne vidiš, zašto se trapimo ako ti ne znaš?” Gle, u dan kad postite poslove nalazite i na posao gonite radnike svoje."},{"v":4,"t":"Gle, vi postite da se prepirete i svađate i da pesnicom bijete siromahe. Ne postite više kao danas, i čut će vam se glas u visini!"},{"v":5,"t":"Zar je meni takav post po volji u dan kad se čovjek trapi? Spuštati kao rogoz glavu k zemlji, sterati poda se kostrijet i pepeo, hoćeš li to zvati postom i danom ugodnim Jahvi?"},{"v":6,"t":"Ovo je post koji mi je po volji, riječ je Jahve Gospoda: Kidati okove nepravedne, razvezivat' spone jarmene, puštati na slobodu potlačene, slomiti sve jarmove;"},{"v":7,"t":"podijeliti kruh svoj s gladnima, uvesti pod krov svoj beskućnike, odjenuti onog koga vidiš gola i ne kriti se od onog tko je tvoje krvi."},{"v":8,"t":"Tad će sinut' poput zore tvoja svjetlost, i zdravlje će tvoje brzo procvasti. Pred tobom će ići tvoja pravda, a Slava Jahvina bit će ti zalaznicom."},{"v":9,"t":"Vikneš li, Jahve će ti odgovorit, kad zavapiš, reći će: “Evo me!” Ukloniš li iz svoje sredine jaram, ispružen prst i besjedu bezbožnu,"},{"v":10,"t":"dadeš li kruha gladnome, nasitiš li potlačenog, tvoja će svjetlost zasjati u tmini i tama će tvoja kao podne postati,"},{"v":11,"t":"Jahve će te vodit' bez prestanka, sitit će te u sušnim krajevima. On će krijepit' kosti tvoje i bit ćeš kao vrt zaljeven, kao studenac kojem voda nikad ne presuši."},{"v":12,"t":"I ti ćeš gradit' na starim razvalinama, dići ćeš temelje budućih koljena. Zvat će te popravljačem pukotina i obnoviteljem cesta do naselja."},{"v":13,"t":"Zadržiš li nogu da ne pogaziš subotu i u sveti dan ne obavljaš poslove; nazoveš li subotu milinom a časnim dan Jahvi posvećen; častiš li ga odustajuć' od puta, bavljenja poslom i pregovaranja -"},{"v":14,"t":"tad ćeš u Jahvi svoju milinu naći, i ja ću te provesti po zemaljskim visovima, dat ću ti da uživaš u baštini oca tvog Jakova, jer Jahvina su usta govorila."}]},"59":{"hr":[{"v":1,"t":"Ne, nije ruka Jahvina prekratka da spasi, niti mu je uho otvrdlo da ne bi čuo,"},{"v":2,"t":"nego su opačine vaše jaz otvorile između vas i Boga vašega. Vaši su grijesi lice njegovo zastrli, i on vas više ne sluša."},{"v":3,"t":"Jer ruke su vaše u krvi ogrezle, a vaši prsti u zločinima. Usne vam izgovaraju laž, a jezik podlost mrmlja."},{"v":4,"t":"Nitko s pravom tužbu ne podiže, niti koga sude po istini. U ništavilo se uzdaju, laž kazuju, začinju zloću, a rađaju bezakonje."},{"v":5,"t":"Legu jaja gujina, tkaju mrežu paukovu; pojede li tko njihovo jaje, umire, razbije li ga, iz njega ljutica izlazi."},{"v":6,"t":"Njihovim tkanjem nemoguće se odjenuti, ne možeš se pokriti njihovom rukotvorinom. Rukotvorine su njihove djela zločinačka, rukama svojim čine nasilje."},{"v":7,"t":"Noge njihove u zlo hitaju i brze su da krv nevinu proliju. Misli su im misli zločinačke, pustoš i propast na njinim su putima."},{"v":8,"t":"Put mira oni ne poznaju, na stazama njihovim nema pravice. Iskrivili su svoje putove, tko njima kreće mira ne poznaje."},{"v":9,"t":"Stog' se pravo od nas udaljilo, zato pravda ne dopire do nas. Nadasmo se svjetlosti, a ono tama; i vidjelu, a ono u tmini hodimo."},{"v":10,"t":"Pipamo kao slijepci duž zida, tapkamo kao bez očiju. Spotičemo se u podne k'o u sumraku, sasvim zdravi, kao da smo mrtvi."},{"v":11,"t":"Svi mumljamo kao medvjedi i gučemo tužno kao golubovi. Očekivasmo Sud, a njega nema, i spasenje - od nas je daleko."},{"v":12,"t":"Jer mnogo je naših opačina pred tobom i grijesi naši protiv nas svjedoče. Doista, prijestupi su naši pred nama, mi znademo svoju krivicu;"},{"v":13,"t":"pobunili smo se i zanijekali Jahvu, odmetnuli se od Boga svojega, govorili podlo, odmetnički, mrmljali u srcu riječi lažljive."},{"v":14,"t":"Tako je potisnuto pravo, i pravda mora stajati daleko. Jer na trgu posrnu istina i poštenju nema više pristupa."},{"v":15,"t":"Vjernosti je ponestalo, a tko izbjegava zlo, bude opljačkan. Jahve vidje, i ne bi mu milo što nema pravice."},{"v":16,"t":"Vidje da nema čovjeka, začudi se što nema posrednika. Tad mu pomože njegova mišica i njegova ga pravda poduprije."},{"v":17,"t":"Pravednost je obukao k'o oklop, stavio na glavu kacigu spasenja. Osvetom se odjenuo k'o haljom, ogrnu se revnošću kao plaštem."},{"v":18,"t":"Vratit će svakome po njegovim djelima: gnjev svojim protivnicima, odmazdu dušmanima."},{"v":19,"t":"Sa zapada vidjet će ime Jahvino i Slavu njegovu s istoka sunčanog. Jer doći će kao uska rijeka koju goni dah Jahvin."},{"v":20,"t":"Ali doći će Otkupitelj Sionu, i onima od sinova Jakovljevih koji se obrate od svog otpadništva, riječ je Jahvina."},{"v":21,"t":"“A ovo je moj Savez s njima,” govori Jahve. “Duh moj koji je na tebi i riječi moje koje stavih u tvoja usta neće izići iz usta tvojih ni usta tvojega potomstva, ni iz usta potomstva tvojih potomaka, od sada pa dovijeka,” veli Jahve."}]},"60":{"hr":[{"v":1,"t":"Ustani, zasini, jer svjetlost tvoja dolazi, nad tobom blista Slava Jahvina."},{"v":2,"t":"A zemlju, evo, tmina pokriva, i mrklina narode! A tebe obasjava Jahve, i Slava se njegova javlja nad tobom."},{"v":3,"t":"K tvojoj svjetlosti koračaju narodi, i kraljevi k istoku tvoga sjaja."},{"v":4,"t":"Podigni oči, obazri se: svi se sabiru, k tebi dolaze. Sinovi tvoji dolaze izdaleka, kćeri ti nose u naručju."},{"v":5,"t":"Gledat ćeš tad i sjati radošću, igrat će srce i širit' se, jer k tebi će poteći bogatstvo mora, blago naroda k tebi će pritjecati."},{"v":6,"t":"Mnoštvo deva prekrit će te, jednogrbe deve iz Midjana i Efe. Svi će iz Šebe doći donoseći zlato i tamjan i hvale Jahvi pjevajući."},{"v":7,"t":"Sva stada kedarska u tebi će se sabrati, ovnovi nebajotski bit će ti na službu. Penjat će se k'o ugodna žrtva na moj žrtvenik, proslavit ću Dom Slave svoje!"},{"v":8,"t":"Tko su oni što lebde poput oblaka, k'o golubovi prema golubinjacima svojim?"},{"v":9,"t":"Da, to se zbog mene sabiru brodovi, lađe su taršiške pred njima da izdaleka dovezu tvoje sinove, a s njima srebro njihovo i zlato, zbog imena Jahve, Boga tvojega, zbog Sveca Izraelova koji te proslavi."},{"v":10,"t":"Zidine će tvoje obnoviti stranci i kraljevi njihovi služit će ti. U svojoj srdžbi ja sam te udario, al' u svojoj naklonosti opet ti se smilovah."},{"v":11,"t":"Vrata će tvoja biti otvorena svagda, ni danju ni noću neće se zatvarati, da propuste k tebi bogatstva naroda s kraljevima koji ih vode."},{"v":12,"t":"Jer propast će narod i kraljevstvo koje ti ne bude htjelo služiti, i ti će se narodi sasvim zatrti."},{"v":13,"t":"K tebi će doći slava Libanona, čempresi, jele i brijestovi skupa, da ukrase prostor mojega Svetišta, podnožje će moje proslaviti!"},{"v":14,"t":"K tebi će, sagnuti, dolaziti sinovi tvojih tlačitelja, pred noge ti padat' koji te prezirahu. Nazivat će te Gradom Jahvinim, Sionom Sveca Izraelova."},{"v":15,"t":"Zato što si bio ostavljen, omražen, izbjegavan, učinit ću te vječnim ponosom, radošću od koljena do koljena."},{"v":16,"t":"Ti ćeš sisati mlijeko naroda, sisat ćeš grudi kraljeva. I znat ćeš da sam ja, Jahve, Spasitelj tvoj, Silni Jakovljev, tvoj Otkupitelj."},{"v":17,"t":"Mjesto mjedi, donijet ću zlato; mjesto željeza, donijet ću srebro; mjesto drva, mjed; mjesto kamena, željezo. Za glavara tvoga postavit ću Mir, Pravdu za vladara."},{"v":18,"t":"Više se neće slušat' o nasilju u tvojoj zemlji ni o pustošenju i razaranju na tvojem području. Zidine ćeš svoje nazivati Spasom, Slavom svoja vrata."},{"v":19,"t":"Neće ti više sunce biti svjetlost danju nit' će ti svijetlit' mjesečina, nego će Jahve biti tvoje vječno svjetlo i tvoj će Bog biti tvoj sjaj."},{"v":20,"t":"Sunce tvoje neće više zalaziti nit' će ti mjesec pomrčati, jer će Jahve biti tvoje vječno svjetlo, i okončat će se dani tvoje žalosti."},{"v":21,"t":"Svi u tvom narodu bit će pravednici i posjedovat će zemlju dovijeka, mog nasada izdanci, mojih ruku djelo, da bih se u njima proslavio."},{"v":22,"t":"Od najmanjega postat će tisuća, od neznatnoga moćan narod. Ja, Jahve, govorio sam; u pravo ću vrijeme izvršiti."}]},"61":{"hr":[{"v":1,"t":"Duh Jahve Gospoda na meni je, jer me Jahve pomaza, posla me da radosnu vijest donesem ubogima, da iscijelim srca slomljena; da zarobljenima navijestim slobodu i oslobođenje sužnjevima;"},{"v":2,"t":"da navijestim godinu milosti Jahvine i dan odmazde Boga našega; da razveselim ožalošćene na Sionu"},{"v":3,"t":"i da im dadem vijenac mjesto pepela, ulje radosti mjesto ruha žalosti, pjesmu zahvalnicu mjesto duha očajna. I zvat će ih Hrastovima pravde, Nasadom Jahvinim - na slavu njegovu."},{"v":4,"t":"Oni će nanovo dići drevne razvaline, sazdati opet mjesta poharana, ruševine prošlih pokoljenja."},{"v":5,"t":"Tuđinci će doći da vam stada pasu, stranci će vam biti ratari i vinogradari."},{"v":6,"t":"A vas će zvati “Svećenici Jahvini”, nazivat će vas “Službenici Boga našega”. Uživat ćete bogatstva naroda, blagom se njihovim dičiti."},{"v":7,"t":"Dvostruka bijaše njihova sramota - rug i prezir bijahu im baština - zato će u zemlji svojoj baštinit' dvostruko, njihova će biti radost vječita."},{"v":8,"t":"Jer ja, Jahve, ljubim pravdu, a mrzim grabež nepravedni. Vjerno ću ih nagraditi i sklopiti s njima Savez vječni."},{"v":9,"t":"Slavno će im biti sjeme među pucima i potomstvo među narodima. Tko god ih vidi, prepoznat će da su sjeme što ga Jahve blagoslovi."},{"v":10,"t":"Radošću silnom u Jahvi se radujem, duša moja kliče u Bogu mojemu, jer me odjenu haljinom spasenja, zaogrnu plaštem pravednosti, kao ženik kad sebi vijenac stavi il' nevjesta kad se uresi nakitom."},{"v":11,"t":"Kao što zemlja tjera svoje klice, kao što u vrtu niče sjemenje, učinit će Gospod da iznikne pravda i hvala pred svim narodima."}]},"62":{"hr":[{"v":1,"t":"Sionu za ljubav neću šutjeti, Jeruzalema radi neću mirovati dok pravda njegova ne zasine k'o svjetlost, dok njegovo spasenje ne plane k'o zublja."},{"v":2,"t":"I puci će vidjet' tvoju pravednost, i tvoju slavu svi kraljevi; prozvat će te novim imenom što će ga odrediti usta Jahvina."},{"v":3,"t":"U Jahvinoj ćeš ruci biti kruna divna i kraljevski vijenac na dlanu Boga svog."},{"v":4,"t":"Neće te više zvati Ostavljenom ni zemlju tvoju Opustošenom, nego će te zvati Moja milina, a zemlju tvoju Udata, jer ti si milje Jahvino i zemlja će tvoja imat' supruga."},{"v":5,"t":"Kao što se mladić ženi djevicom, tvoj će se graditelj tobom oženiti; i kao što se ženik raduje nevjesti, tvoj će se Bog tebi radovati."},{"v":6,"t":"Na zidine tvoje, Jeruzaleme, stražare sam postavio: ni danju ni noću ne smiju zašutjeti. O, vi koji podsjećate Jahvu, vama nema počinka!"},{"v":7,"t":"I ne dajte mu mira dok ne obnovi Jeruzalem, dok ga opet slavom na zemlji ne učini."},{"v":8,"t":"Zakle se Gospod desnicom i mišicom svojom snažnom: “Neću više dati žita tvoga za hranu neprijateljima. Neće više tuđinci piti tvoga vina o kojem si teško radio."},{"v":9,"t":"Neka ga jedu oni koji su ga želi i neka hvale Jahvu, neka ga piju oni što su ga trgali u predvorju mojega Svetišta!”"},{"v":10,"t":"Prođite, prođite kroz vrata, poravnajte put narodu! Nasipajte, nasipajte cestu, uklonite s nje kamenje. Podignite stijeg narodima!"},{"v":11,"t":"Evo, Jahve oglasuje do nakraj zemlje: “Recite kćeri sionskoj: Evo, dolazi tvoj spasitelj. Evo, s njim naplata njegova i njegova nagrada ispred njega!"},{"v":12,"t":"Oni će se zvati 'Sveti narod', 'Otkupljenici Jahvini'. A tebe će zvati 'Traženi' - 'Grad neostavljeni'.”"}]},"63":{"hr":[{"v":1,"t":"Tko je taj što dolazi iz Edoma, iz Bosre, u haljinama crvenim? Tko je taj što veličanstveno odjenut pun snage korača? - Ja sam to koji naučavam pravdu, velik kad spasavam!"},{"v":2,"t":"- Zašto je crvena tvoja haljina i odijelo kao u onog koji gazi u kaci?"},{"v":3,"t":"- U kaci sam sam gazio, od narodÄa nikog ne bijaše. U gnjevu ih svom izgazih i zgnječih u svojoj jarosti. Krv mi njihova poprska haljine, iskaljah svu odjeću svoju."},{"v":4,"t":"Jer dan osvete bijaše mi u srcu, došla je godina mojeg otkupljenja."},{"v":5,"t":"Ogledah se, al' ne bješe pomoćnika! Začudih se, al' ne bješe potpore. Tada mi je moja mišica pomogla i moja me srdžba poduprla."},{"v":6,"t":"U gnjevu svom satrijeh narode, u bijesu sve ih izgazih i zemlju polih krvlju njihovom!"},{"v":7,"t":"Slavit ću ljubav Jahvinu, slavna djela njegova - za sve što nam Jahve učini, za veliku dobrotu domu Izraelovu što nam je iskaza u svojoj samilosti, u obilju svoje ljubavi."},{"v":8,"t":"Reče: “Dosta, oni su narod moj, sinovi koji se neće iznevjeriti!” I on im posta Spasiteljem u svim njihovim tjeskobama."},{"v":9,"t":"Nije slao poslanika ni anđela nego ih je sam spasio. U svojoj ljubavi i samilosti sam ih je otkupio, podigao ih i nosio u sve dane od davnine."},{"v":10,"t":"Ali se oni odmetnuše, ožalostiše sveti Duh njegov. Zato im je postao neprijatelj i sam je na njih zavojštio."},{"v":11,"t":"Spomenuše se tad davnih dana i sluge njegova Mojsija: “Gdje li je onaj koji izvuče iz vode pastira stada svojega? Gdje je onaj koji udahnu u njega Duh svoj sveti?"},{"v":12,"t":"Koji je Mojsijevu desnicu vodio veličanstveno svojom mišicom, koji vodu pred njima razdvoji i steče sebi ime vječno;"},{"v":13,"t":"koji ih provede dnom bezdana kao konja po pustinji i nisu se spoticali?"},{"v":14,"t":"Poput stoke što silazi u dolinu, Duh Jahvin vodio ih počivalištu. Tako si ti vodio narod svoj i slavno ime sebi stekao."},{"v":15,"t":"Pogledaj s nebesa i vidi iz prebivališta svoga svetog i slavnog. Gdje li je ljubomora tvoja i snaga? Zar se susteglo ganuće tvog srca i samilost tvoja prema meni? Ah, sućuti nam svoje ne ustegni,"},{"v":16,"t":"jer Otac si naš! Abraham nas ne poznaje i ne spominje nas se Izrael; Jahve, ti si naš Otac, Otkupitelj naš - ime ti je oduvijek."},{"v":17,"t":"Zašto, o Jahve, zašto nas puštaš da lutamo daleko od tvojih putova, zašto si dao da nam srce otvrdne da se tebe više ne bojimo? Vrati se, radi slugu svojih i radi plemenÄa što su tvoja baština!"},{"v":18,"t":"Zašto bezbožnici gaze tvoje Svetište, a neprijatelji naši blate tvoju svetinju?"},{"v":19,"t":"Odavna postadosmo kao oni kojima više ne vladaš i koji tvoje ime više ne nose. O, da razdreš nebesa i siđeš, da ime svoje objaviš neprijateljima: pred licem tvojim tresla bi se brda, pred tobom bi drhtali narodi,"}]},"64":{"hr":[{"v":1,"t":"kao kad oganj suho granje zapali i vatra vodu zakuha!"},{"v":2,"t":"Čineć' djela strahotna, neočekivana, silazio si i brda su se tresla pred tobom!"},{"v":3,"t":"Odvijeka se čulo nije, uho nijedno nije slušalo, oko nijedno nije vidjelo, da bi koji bog, osim tebe, takvo što činio onima koji se uzdaju u njega."},{"v":4,"t":"Pomažeš onima što pravdu čine radosno i tebe se spominju na putima tvojim; razgnjevismo te, griješismo, od tebe se odmetnusmo."},{"v":5,"t":"Tako svi postasmo nečisti, a sva pravda naša k'o haljine okaljane. Svi mi k'o lišće otpadosmo i opačine naše k'o vjetar nas odnose."},{"v":6,"t":"Nikog nema da tvoje ime prizove, da se probudi i osloni o tebe. Jer lice si svoje od nas sakrio i predao nas u ruke zločinima našim."},{"v":7,"t":"Pa ipak, naš si otac, o Jahve: mi smo glina, a ti si naš lončar - svi smo mi djelo ruku tvojih."},{"v":8,"t":"Ne srdi se, Jahve, odveć žestoko, ne spominji se bez prestanka naše krivice. De pogledaj - tÓa svi smo mi narod tvoj!"},{"v":9,"t":"Opustješe sveti gradovi tvoji, Sion pustinja posta, i pustoš Jeruzalem."},{"v":10,"t":"Dom, svetinja naša i ponos naš, u kom te oci naši slavljahu, ognjem izgori i sve su nam dragocjenosti opljačkane."},{"v":11,"t":"Zar ćeš se na sve to, Jahve, sustezati, zar ćeš šutjet' i ponižavati nas odveć žestoko?"}]},"65":{"hr":[{"v":1,"t":"Potražiše me koji ne pitahu za me, nađoše me koji me ne tražahu; rekoh: “Evo me! Evo me!” narodu koji ne prizivaše ime moje."},{"v":2,"t":"Svagda sam pružao ruku narodu odmetničkom, koji hodi putem zlim, za mislima svojim,"},{"v":3,"t":"narodu koji me bez prestanka u lice srdi: žrtvuju po vrtovima, kad prinose na opekama,"},{"v":4,"t":"na grobovima stanuju i noće na skrovitim mjestima, jedu svinjetinu, meću u zdjele jela nečista."},{"v":5,"t":"I još govore: “Ukloni se! Ne prilazi mi da te ne posvetim.” Oni su mi dim u nosu, oganj što gori povazdan."},{"v":6,"t":"Evo, sve je napisano preda mnom: neću ušutjet' dok im ne platim, dok im ne platim u njedra,"},{"v":7,"t":"za bezakonja vaša i vaših otaca, sva zajedno - govori Jahve. Koji su prinosili kad na gorama i pogrđivali me na brežuljcima - izmjerit ću im u krilo plaću za djela prijašnja."},{"v":8,"t":"Ovako govori Jahve: “Kao što o soku u grozdu vele: 'Ne uništavajte ga, u njemu je blagoslov!' tako ću učiniti i ja radi slugu svojih, neću sve uništiti."},{"v":9,"t":"Izvest ću iz Jakova potomstvo, a iz Jude baštinika gora svojih; baštinit će ih odabranici moji, i moje će se sluge ondje naseliti."},{"v":10,"t":"Šaron će postati pašnjak ovcama, a nizina akorska počivalište govedima - narodu mojem koji mene traži."},{"v":11,"t":"A vi koji ste Jahvu ostavili, koji ste zaboravili Svetu goru moju, koji pripremate stol Gadu, koji Meniju naljev lijevate,"},{"v":12,"t":"za mač sam vas odredio - past ćete ničice da vas kolju. Jer zvao sam vas, a vi se niste odazvali, govorio sam, a vi niste slušali, nego ste činili što je zlo u očima mojim, izabirali ste što mi nije po volji.”"},{"v":13,"t":"Stog ovako Jahve Gospod govori: “Evo, sluge će moje jesti, a vi ćete gladovati. Evo, sluge će moje piti, a vi ćete žeđati. Evo, sluge će se moje veseliti, a vi ćete se stidjeti."},{"v":14,"t":"Evo, sluge će se moje radovati od sreće u srcu, a vi ćete vikati od boli u srcu i kukati duše slomljene!"},{"v":15,"t":"Ime ćete svoje ostaviti za kletvu mojim izabranicima: 'Tako te ubio Jahve!' A sluge svoje on će zvati drugim imenom."},{"v":16,"t":"Tko se u zemlji bude blagoslivljao, nek' se blagoslivlje Bogom vjernim. I tko se u zemlji bude kleo, nek' se kune Bogom vjernim. Jer prijašnje će nevolje biti zaboravljene, od očiju mojih bit će sakrivene."},{"v":17,"t":"Jer, evo, ja stvaram nova nebesa i novu zemlju. Prijašnje se više neće spominjati niti će vam na um dolaziti."},{"v":18,"t":"Veselite se i dovijeka kličite zbog onoga što ja stvaram; jer, evo, od Jeruzalema stvaram klicanje, od naroda njegova radost."},{"v":19,"t":"I klicat ću nad Jeruzalemom, radovat' se nad svojim narodom. U njemu više neće čuti ni plača ni vapaja."},{"v":20,"t":"U njemu više neće biti novorođenčeta koje živi malo dana ni starca koji ne bi godina svojih navršio: najmlađi će umrijet' kao stogodišnjak, a tko ne doživi stotinu godina prokletim će se smatrati."},{"v":21,"t":"Gradit će kuće i stanovat' u njima, saditi vinograde i uživati rod njihov."},{"v":22,"t":"Neće se više graditi da drugi stanuju ni saditi da drugi uživa: vijek naroda moga bit će k'o vijek drveta, izabranici moji dugo će uživati plodove ruku svojih."},{"v":23,"t":"Neće se zalud mučiti i neće rađati za smrt preranu, jer će oni s potomcima svojim biti rod blagoslovljenika Jahvinih."},{"v":24,"t":"Prije nego me zazovu, ja ću im se odazvat'; još će govoriti, a ja ću ih već uslišiti."},{"v":25,"t":"Vuk i jagnje zajedno će pasti, lav će jesti slamu k'o govedo; al' će se zmija prahom hraniti. Nitko neće činiti zla ni štete na svoj Svetoj gori mojoj” - govori Jahve."}]},"66":{"hr":[{"v":1,"t":"Ovako govori Jahve: “Nebesa su moje prijestolje, a zemlja podnožje nogama! Kakvu kuću da mi sagradite i gdje da bude mjesto mog prebivališta?"},{"v":2,"t":"TÓa sve je moja ruka načinila i sve je moje” - riječ je Jahvina. “Ali na koga svoj pogled svraćam? Na siromaha i čovjeka duha ponizna koji od moje riječi dršće."},{"v":3,"t":"Ima ih koji kolju bika, ali i ljude ubijaju; žrtvuju ovcu, ali i psu vrat lome. Netko prinosi žrtvu, ali i krv svinjsku; prinose kad, ali časte i kipove. Kao što oni izabraše svoje putove i duši im se mile gnusobe njihove,"},{"v":4,"t":"tako ću i ja izabrati za njih nevolje nesmiljene, pustit ću na njih ono čega se plaše. Jer zvao sam, a nitko se ne odazva, govorio sam, a nitko ne posluša, nego su činili što je zlo u očima mojim, izabrali ono što mi nije po volji.”"},{"v":5,"t":"Poslušajte riječ Jahvinu, vi koji od njegove riječi dršćete. “Govore braća vaša koja na vas mrze i odbacuju vas radi moga imena: 'Neka se proslavi Jahve, pa da radost vašu vidimo.' Ali oni će biti postiđeni.”"},{"v":6,"t":"Čuj! Buka iz grada, glas iz Hrama! Glas je to Jahve koji uzvraća svojim neprijateljima."},{"v":7,"t":"Prije neg' bolove oćutje, eto je rodila. Prije neg' trudove osjeti, porodi dječaka."},{"v":8,"t":"Tko je takvo što čuo, tko je takvo što vidio? Može li se zemlja u jednom danu napučiti? Može li se narod odjednom roditi? A tek što je osjetila trudove, Sionka rodi sinove!"},{"v":9,"t":"“Zar bih ja otvorio krilo materino a da ono ne rodi?” - govori Jahve. “Zar bih ja, koji dajem rađanje, zatvorio maternicu?” - kaže Bog tvoj."},{"v":10,"t":"Veselite se s Jeruzalemom, kličite zbog njega svi koji ga ljubite! Radujte se, radujte s njime svi koji ste nad njim tugovali!"},{"v":11,"t":"Nadojite se i nasitite na dojkama utjehe njegove da se nasišete i nasladite na grudima krepčine njegove."},{"v":12,"t":"Jer ovako govori Jahve: “Evo, mir ću na njih kao rijeku svratiti i kao potok nabujali bogatstvo naroda. Dojenčad ću njegovu na rukama nositi i milovati na koljenima."},{"v":13,"t":"Kao što mati tješi sina, tako ću i ja vas utješiti - utješit ćete se u Jeruzalemu.”"},{"v":14,"t":"Kad to vidite, srce će vam se radovati i procvast će vam kosti k'o mlada trava. Očitovat će se ruka Jahvina na njegovim slugama i gnjev nad neprijateljima njegovim."},{"v":15,"t":"Jer, evo, dolazi Jahve s ognjem - bojna su mu kola poput vihora - da u jarosti gnjev svoj iskali i prijetnje svoje u ognju žarkome."},{"v":16,"t":"Da, sudit će Jahve ognjem i mačem svakom smrtniku: pobijenih Jahvinih mnoštvo će biti."},{"v":17,"t":"Oni koji se posvećuju i čiste u vrtovima iza onog jednog u sredini, koji jedu svinjetinu, nečisto i miševe - svi će zajedno izginuti, riječ je Jahvina."},{"v":18,"t":"Ja dobro poznajem njihova djela i namjere njihove. “Dolazim da saberem sve puke i jezike, i oni će doći i vidjeti moju Slavu!"},{"v":19,"t":"Postavit ću im znak i poslat ću preživjele od njih k narodima u Taršiš, Put, Lud, Mošek, Roš, Tubal i Javan - k dalekim otocima koji nisu čuli glasa o meni ni vidjeli moje Slave - i oni će naviještati Slavu moju narodima."},{"v":20,"t":"I dovest će svu vašu braću između svih naroda kao prinos Jahvi - na konjima, na bojnim kolima, nosilima, na mazgama i jednogrbim devama - na Svetu goru svoju u Jeruzalemu” - govori Jahve - “kao što sinovi Izraelovi prinose prinos u čistim posudama u Domu Jahvinu."},{"v":21,"t":"I uzet ću sebi između njih svećenike, levite” - govori Jahve."},{"v":22,"t":"“Jer, kao što će nova nebesa i zemlja nova, koju ću stvoriti, trajati preda mnom” - riječ je Jahvina - “tako će vam ime i potomstvo trajati."},{"v":23,"t":"Od mlađaka do mlađaka, od subote do subote, dolazit će svi ljudi da se poklone pred licem mojim” - govori Jahve."},{"v":24,"t":"Izlazeći, gledat ću trupla ljudi koji se od mene odmetnuše: crv njihov neće umrijeti i njihov se oganj neće ugasiti - bit će na gadost svim ljudima."}]}},"JER":{"1":{"hr":[{"v":1,"t":"Riječi Jeremije, sina Hilkijina, svećenika iz Anatota, u zemlji Benjaminovoj."},{"v":2,"t":"Njemu dođe riječ Jahvina, u dane Jošije, sina Amonova, kralja Judina, trinaeste godine vladanja njegova:"},{"v":3,"t":"zatim u dane Jojakima, sina Jošijina, kralja Judina, do svršetka jedanaeste godine Sidkije, sina Jošijina, kralja Judeje sve do Jeruzalema, u petom mjesecu izgnanstva."},{"v":4,"t":"Dođe mi riječ Jahvina:"},{"v":5,"t":"“Prije nego što te oblikovah u majčinoj utrobi, ja te znadoh; prije nego što iz krila majčina izađe, ja te posvetih, za proroka svim narodima postavih te.”"},{"v":6,"t":"A ja rekoh: “Ah, Gospode Jahve, gle, ja ne umijem govoriti: dijete sam.”"},{"v":7,"t":"A Jahve mi odvrati: “Ne govori: 'Dijete sam!' Već idi k onima kojima te šaljem i reci sve ono što ću ti narediti."},{"v":8,"t":"Ne boj ih se: jer ja sam s tobom da te izbavim,” riječ je Jahvina."},{"v":9,"t":"I tada Jahve pruži ruku, dotače se usta mojih i reče: “Evo, u usta tvoja stavljam riječi svoje."},{"v":10,"t":"Gle: postavljam te danas nad narode i kraljevstva, da istrebljuješ i rušiš, da zatireš i ništiš, da gradiš i sadiš.”"},{"v":11,"t":"I dođe mi riječ Jahvina: “Što vidiš, Jeremija?” A ja ću: “Vidim granu bademovu.”"},{"v":12,"t":"Tada mi Jahve reče: “Dobro vidiš, jer ja bdim nad riječima svojim da ih ispunim!”"},{"v":13,"t":"I dođe mi riječ Jahvina: “Što vidiš?” A ja ću: “Vidim uzavrio lonac, a otvor mu gleda na sjever.”"},{"v":14,"t":"I Jahve mi reče: “Sa sjevera buknut će zlo protiv svih stanovnika ove zemlje."},{"v":15,"t":"Jer evo, ja ću sazvati sva sjeverna kraljevstva” - riječ je Jahvina. “I ona će doći: svako će od njih staviti svoje prijestolje pred ulaz vrata Jeruzalema, protiv svih zidina njegovih, i protiv svih gradova judejskih."},{"v":16,"t":"I sudit ću im za sve opačine njihove; zato što me ostaviše, zato što kadiše drugim bogovima i klanjahu se djelima ruku svojih."},{"v":17,"t":"Ti bedra svoja sad opaši, ustaj, pa ćeš im govoriti sve što ću tebi zapovjediti. Ne dršći pred njima, da ne bih morao učiniti da uzdršćeš pred njima."},{"v":18,"t":"Danas te, evo, postavljam kao grad utvrđeni, kao stup željezni, k'o zidinu brončanu protiv sve zemlje: protiv kraljeva i knezova judejskih, svećenika i naroda ove zemlje."},{"v":19,"t":"I borit će se s tobom, al' te neće nadvladati, jer ja sam s tobom da te izbavim,” riječ je Jahvina."}]},"2":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Idi i viči u uši Jeruzalemu: Ovako govori Jahve: Spominjem se mladosti tvoje privržene, ljubavi tvoje vjereničke: ti pođe za mnom u pustinju, po zemlji gdje se ne sije."},{"v":3,"t":"Izrael bijaše Jahvi svetinja, prvina plodova njegovih; tko god od njih jeđaše, bijaše kažnjen; zlo ga snađe” - riječ je Jahvina."},{"v":4,"t":"“Čujte riječ Jahvinu, dome Jakovljev, i svi rodovi doma Izraelova."},{"v":5,"t":"Ovako govori Jahve: 'Kakvu nepravdu nađoše oci vaši na meni te se udaljiše od mene? Za ispraznošću pođoše, te sami isprazni postadoše."},{"v":6,"t":"Ne pitahu: Gdje je Jahve koji nas izvede iz zemlje egipatske te nas vođaše kroz pustinju, po zemlji pustoj, jedva prohodnoj, po zemlji suhoj i mračnoj, po zemlji kojom nitko ne prolazi, nit' se tko nastanjuje?'"},{"v":7,"t":"U zemlju vinograda i maslinika ja vas dovedoh, da se hranite plodom i dobrotom njezinom. Ali tek što uđoste, zemlju moju oskvrnuste i baštinu moju u gnusobu pretvoriste."},{"v":8,"t":"Svećenici ne govorahu: 'Gdje je Jahve?' Tumači Zakona mene ne upoznaše, pastiri otpadoše od mene, a proroci prorokovahu u ime Baalovo i iđahu za onima što im pomoći ne mogoše."},{"v":9,"t":"Zato ću još parnicu voditi s vama - riječ je Jahvina - i parbit ću se sa sinovima sinova vaših."},{"v":10,"t":"Pođite, dakle, na otoke kitimske, da vidite, ili u Kedar pošljite izvidnice te dobro promislite i provjerite je li se igda što slično zbilo."},{"v":11,"t":"Je li koji narod mijenjao bogove - oni čak i nisu bogovi! A narod moj Slavu svoju zamijeni za one što ne pomažu!"},{"v":12,"t":"Zapanjite se nad tim, nebesa, zgranite se i zaprepastite,” riječ je Jahvina."},{"v":13,"t":"“Jer dva zla narod moj učini: ostavi mene, Izvor vode žive, te iskopa sebi kladence, kladence ispucane što vode držati ne mogu."},{"v":14,"t":"Je li Izrael rob il' sluga u kući rođen? Zašto plijenom posta?"},{"v":15,"t":"Lavovi su na nj rikali, podizali glas svoj. U pustoš pretvoriše zemlju njegovu, gradove popališe, nema im žitelja."},{"v":16,"t":"Čak i oni iz Memfisa i Tafnisa brijahu ti tjeme."},{"v":17,"t":"Nisi li to sam sebi učinio otpavši od Jahve, Boga svojega?"},{"v":18,"t":"A sad, zašto krećeš u Egipat da piješ vode iz Nila? Zašto krećeš u Asiriju da piješ vode iz Rijeke?"},{"v":19,"t":"Opačina te tvoja kažnjava, otpadništvo te tvoje osuđuje. Shvati i vidi kako je teško i gorko što ostavi Jahvu, Boga svojega, što više nema straha mog u tebi” - riječ je Gospoda Jahve nad Vojskama."},{"v":20,"t":"“Da, odavna ti slomi jaram svoj, raskide veze što te vezahu i reče: 'Neću da robujem.' Pa ipak, na svakom povišem humu, pod svakim drvetom zelenim lijegao si k'o bludnica."},{"v":21,"t":"A ja te zasadih kao lozu izabranu, k'o sadnicu plemenitu. Kako li mi se samo prometnu u jalov izrod, u lozu divlju!"},{"v":22,"t":"Da se i lužinom opereš, napravljenom od mnogo pepela, ostat će mrlja bezakonja tvoga preda mnom” - riječ je Jahve Gospoda."},{"v":23,"t":"“Kako samo možeš reći: 'Nisam se uprljala, za baalima nisam trčala.' Pogledaj tragove svoje u Dolini, upoznaj što si učinila. Deva brza što krstari stazama svojim,"},{"v":24,"t":"magarica divlja navikla na pustinju, u pohoti svojoj požudno dašće, tko da je ukroti u vrijeme gonjenja? Tko god je traži, neće se umoriti, naći će je u mjesecu njezinu."},{"v":25,"t":"Čuvaj se da ti noga ne obosi, grlo se ne osuši. A ti kažeš: 'Ne, uzalud je! Jer volim strance, i za njima ću ići.'"},{"v":26,"t":"Kao što se lupež zastidi kad ga uhvate, tako će se zastidjeti sinovi - dom Izraelov, oni, kraljevi, knezovi, svećenici i proroci njihovi"},{"v":27,"t":"koji govore drvetu: 'Ti si otac moj!' a kamenu: 'Ti si me rodio!' jer mi leđa okreću, a ne lice, ali u nevolji svojoj zapomažu: 'Ustani, spasi nas!'"},{"v":28,"t":"Gdje su bogovi što ih ti sam načini? Nek' ustanu ako te mogu spasiti u nevolji tvojoj! Jer imaš, o Judejo, bogova koliko i gradova! Koliko Jeruzalem ima ulica, toliko Baal ima žrtvenika."},{"v":29,"t":"Zašto hoćete da se sa mnom parbite? Svi se od mene odmetnuste” - riječ je Jahvina."},{"v":30,"t":"“Zaludu sam udarao sinove vaše: vi iz toga ne uzeste pouke: mačevi vaši rastrgaše vaše proroke kao lav zatornik."},{"v":31,"t":"Kakva li ste roda? Čujte riječ Jahvinu: Zar bijah pustinja Izraelu, il' zemlja mračna? Zašto moj narod govori: 'Slobodu hoćemo, nećemo više k tebi!'"},{"v":32,"t":"Zaboravlja li djevica svoj nakit il' nevjesta pojas svoj? A narod moj mene zaboravi, bezbroj je tomu već dana."},{"v":33,"t":"O, kako li dobro znaš svoj put kad tragaš za ljubavlju! Zato si i na zlo putove svoje navikla."},{"v":34,"t":"Čak su i ruke tvoje omašćene krvlju siromaha nevinih: nisi ih zatekla kako provaljuju vrata tvoja. Da, za sve njih ti ćeš odgovarati."},{"v":35,"t":"A govoriš: 'Nevina sam, gnjev se njegov odvratio od mene.' Evo me da ti sudim jer govoriš: 'Nisam zgriješila.'"},{"v":36,"t":"Kako si jadna u zabludjelosti svojoj! I Egipćani će te posramiti kao što te posramiše Asirci."},{"v":37,"t":"I odavde ćeš morati otići s rukama nad glavom svojom, jer Jahve odbaci one u koje se uzdaš; ti nećeš biti sretna s njima.”"}]},"3":{"hr":[{"v":1,"t":"“Ako muž otpusti ženu svoju i ona ide od njega te se uda za drugoga, ima li još pravo da se vrati njemu? Nije li ta žena sasvim oskvrnuta? A ti si bludničila s mnogim milosnicima, pa da se meni vratiš?” - riječ je Jahvina."},{"v":2,"t":"Podigni oči na goleti i pogledaj: gdje te to nisu oskvrnuli? Na putovima si ih dočekivala kao Arapin u pustinji. Ti si oskvrnula zemlju bludom i opačinom svojom,"},{"v":3,"t":"zato i kiše prestadoše i kasni daždevi ne padoše. Čelo ti je kao u bludnice: ni zacrvenjela se nisi."},{"v":4,"t":"Ne dovikuješ li mi sada: 'Oče moj, ti si prijatelj mladosti moje!"},{"v":5,"t":"Hoće li zauvijek plamtjeti, vječno tinjati gnjev tvoj?' Tako govoriš, a činiš i dalje zla koliko god možeš.”"},{"v":6,"t":"Jahve mi reče u dane kralja Jošije: “Vidje li što učini odmetnica Izrael? Ona odlazi na svaku visoku goru i pod svako zeleno stablo i ondje se podaje bludu."},{"v":7,"t":"A ja mišljah: 'Poslije svega što učini vratit će se k meni.' Ali se ona ne vraća. I to vidje sestra njena, nevjernica Judeja."},{"v":8,"t":"A vidje i kako otpustih odmetnicu Izraela zbog svih preljuba i dadoh joj knjigu otpusnu. Ali sestra joj, nevjernica Judeja, nimalo se ne poboja, pa i ona okrenu u blud."},{"v":9,"t":"I svojim lakoumnim bludom obeščasti zemlju; činila je preljub s kamenjem i drvljem."},{"v":10,"t":"I nakon svega toga nije se vratila k meni nevjernica sestra njezina, Judeja, svim srcem svojim, već samo prijetvorno” - riječ je Jahvina."},{"v":11,"t":"I reče mi Jahve: “Odmetnica Izrael pravednija je od Judeje nevjernice."},{"v":12,"t":"Idi i viči prema Sjeveru ove riječi. Reci: Vrati se, odmetnice, Izraele, riječ je Jahvina. Ne gnjevi se više lice moje na vas, jer sam milostiv - riječ je Jahvina - neću se gnjeviti dovijeka."},{"v":13,"t":"Samo priznaj svoju krivnju da si se odvrgla od Jahve, Boga svojega, i odlutala k tuđincima, pod svako drvo zeleno i nisi slušala glasa mojega - riječ je Jahvina."},{"v":14,"t":"Vratite se, sinovi odmetnici - riječ je Jahvina - jer ja sam vaš Gospodar. Uzet ću vas, po jednoga iz svakoga grada, po dvojicu od svakoga roda, da vas odvedem na Sion."},{"v":15,"t":"I dat ću vam pastire po srcu svojemu koji će vas pasti razumno i mudro."},{"v":16,"t":"A kad se u one dane namnožite i narodite u zemlji - riječ je Jahvina - više se neće govoriti: 'Kovčeg Jahvina Saveza' i nitko neće na nj misliti, nitko ga se neće sjećati ni za njim čeznuti, niti ga ponovo graditi."},{"v":17,"t":"U to će se vrijeme Jeruzalem zvati 'Prijestolje Gospodnje'; i svi će se narodi u njemu sabrati u ime Jahvino, i nijedan se više neće tvrdoglavo povoditi za pokvarenim srcem svojim."},{"v":18,"t":"U one dane slagat će se dom Judin s domom Izraelovim; i zajedno će krenuti iz Zemlje sjeverne u zemlju koju ocima vašim dadoh u baštinu.”"},{"v":19,"t":"A ja rekoh: “Kako da te ubrojim među sinove i dam ti zemlju slasti, baštinu, najljepši biser među narodima! Pomislih: Ti ćeš me zvati 'Oče moj!' i nećeš se više odvratiti od mene.”"},{"v":20,"t":"“Ali kao što se žena iznevjeri mužu svome, tako se i vi iznevjeriste meni, dome Izraelov” - riječ je Jahvina."},{"v":21,"t":"Čuj! Po goletima plač se čuje, zapomaganje djece Izraelove, jer skrenuše s puta svojega. Jahvu, Boga svoga, zaboraviše."},{"v":22,"t":"- Vratite se, sinovi, što se odvratiste, izliječit ću odmetništva vaša! - Evo nas, dolazimo k tebi, jer ti si Jahve, Bog naš!"},{"v":23,"t":"Doista, prijevarni su visovi, graja po brdima. Odista, u Jahvi, Bogu našemu, spasenje je Izraelovo!"},{"v":24,"t":"Baal je proždro trud naših otaca još od mladosti naše: ovce njihove i goveda, nihove kćeri i sinove."},{"v":25,"t":"Lezimo u sramotu svoju, nek' nas pokrije ruglo naše! Jer Jahvi, Bogu svome, sagriješismo mi i oci naši, od mladosti svoje do dana današnjeg, i ne slušamo glasa Jahve, Boga svojega."}]},"4":{"hr":[{"v":1,"t":"“Ako se, Izraele, želiš vratiti - riječ je Jahvina - k meni se vrati; ukloniš li grozote svoje, više ne moraš bježati od mene."},{"v":2,"t":"Ako se zakuneš: 'Živoga mi Jahve!' istinito, pravo i pravedno, narodi će se blagoslivljati u tebi i tobom se dičiti.”"},{"v":3,"t":"Jer ovako govori Jahve Judejcima i Jeruzalemcima: “Prokrčite sebi prljuše, ne sijte po trnjacima."},{"v":4,"t":"Obrežite se Jahvi, skinite obrezak sa srca svojega, Judejci i Jeruzalemci, jer će bijes moj buknuti kao vatra i gorjet će, a nikog da ugasi, zbog zlodjela i opačina što ih počiniste."},{"v":5,"t":"Objavite u Judeji, razglasite u Jeruzalemu! Trubite u rog širom zemlje, vičite punim glasom i recite: 'Svi na okup! Zavucimo se u gradove svoje utvrđene!'"},{"v":6,"t":"Dižite znak prema Sionu! Bježite! Nemojte zastajati! Jer dovodim nesreću sa Sjevera, veliku propast."},{"v":7,"t":"Lav se podiže iz čestara svoga, zatornik naroda izađe iz svog mjesta, krenu da zemlju tvoju opustoši: gradove će tvoje razoriti, nestat će im žitelja."},{"v":8,"t":"Zato se u kostrijet ogrnite, kukajte, naričite, jer rasplamtjela jarost Jahvina nas nije mimoišla."},{"v":9,"t":"U dan onaj - riječ je Jahvina - klonut će srce kralju i knezovima. Svećenici će se zapanjiti, proroci umuknuti."},{"v":10,"t":"I reći će: 'Ah, Jahve, Gospodine, zaista nas teško prevari kad reče: 'Uživat ćete mir' a sad nam je mač pod grlom.'"},{"v":11,"t":"U to će se vrijeme reći narodu ovom i Jeruzalemu: Vruć vjetar s pustinjskih sipina puše prema kćeri naroda moga; ali ne da hladi i da pročisti!"},{"v":12,"t":"Doći će mi vjetar pun prijetnje, i ja ću im tada izreći sud!"},{"v":13,"t":"Gle: diže se k'o oblačine, kola mu slična vihoru, konji brži od orlova. Jao nama! Propadosmo!"},{"v":14,"t":"Operi opačinu sa srca svoga, Jeruzaleme, da bi se spasio. Dokle će se u grudima tvojim misli zločinačke gnijezditi?"},{"v":15,"t":"Jer glas naviješta od Dana, s gore Efrajimove najavljuje nesreću."},{"v":16,"t":"Opomenite, razglasite po Judeji, obznanite Jeruzalemu: neprijatelji dolaze iz daleke zemlje i poklike izvikuju protiv gradova judejskih;"},{"v":17,"t":"poput čuvara poljskih okružuju Jeruzalem, jer se odmetnu od mene” - riječ je Jahvina."},{"v":18,"t":"Put tvoj i djela tvoja to ti učiniše. To je tvoja nesreća! Kako je gorka, kako li pogađa u srce!"},{"v":19,"t":"Utrobo moja! Utrobo moja, bolujem, srce mi se razdire! Dršće mi duša! Ne mogu šutjeti, jer čujem glas roga, poklike bojne."},{"v":20,"t":"Javljaju slom za slomom, sva je zemlja poharana, moji su šatori iznenada opustošeni, u tren oka sva skloništa moja uništena."},{"v":21,"t":"Dokle ću gledati bojne znakove, slušati pozive roga?"},{"v":22,"t":"Da, bezuman je moj narod, ne poznaju me, djeca su oni nerazumna, ništa ne shvaćaju, mudri su tek za zlodjela, al' činiti dobro ne umiju."},{"v":23,"t":"Gledam zemlju: pusta je, evo, i prazna, nebesa: svjetlost im iščezla."},{"v":24,"t":"Gledam brda: gle, tresu se, a svi se humci uzdrmali."},{"v":25,"t":"Gledam: evo čovjeka nema, ptice nebeske sve su odletjele."},{"v":26,"t":"Gledam: plodno polje, evo, opustje, sve gradove razori Jahve žestinom gnjeva svoga."},{"v":27,"t":"Da, ovako govori Jahve: “Sva će zemlja biti poharana, ja ću joj zadati posljednji udarac."},{"v":28,"t":"Na to će se zemlja u crno zaviti, a nebesa, gore, potamnjeti. Jer rekoh, i neću se raskajati, odlučih i neću odustati."},{"v":29,"t":"Pred vikom 'Konjanici i strijelci!' sva se zemlja u bijeg dade: bježe u šipražje, penju se na hridi: svi su gradovi napušteni: nigdje više žive duše."},{"v":30,"t":"A ti, opustošena, što ćeš učiniti? Da se i grimizom zaodjeneš, nakitom zlatnim ukrasiš i oči ličilom izraniš, uzalud se uljepšavaš! Ljubavnici tvoji tebe preziru: traže glavu tvoju."},{"v":31,"t":"Da, jauk kao u bolesnice čujem, vrisak kao u one što prvi put rađa; čuj, to kći sionska jeca i pruža ruke: 'Jao meni! Duša mi zamire pod udarcima ubojica!'"}]},"5":{"hr":[{"v":1,"t":"Prođite ulicama jeruzalemskim, pogledajte dobro i raspitajte se, tražite po njegovim trgovima, pa ako nađete ijednoga čovjeka koji čini pravo i traži istinu, oprostit ću ovom gradu” - riječ je Jahvina."},{"v":2,"t":"Pa kad i govore: “Živoga mi Jahve!” doista se krivo zaklinju."},{"v":3,"t":"Jahve, nisu li oči tvoje upravljene k istini? Biješ ih, ali njih ne boli; zatireš ih, al' oni odbijaju pouku tvoju. Čelo im je tvrđe od litice, odbijaju da se obrate."},{"v":4,"t":"Rekoh: “Samo siromasi tako ludo postupaju, jer ne znaju puta Jahvina ni pravo Boga svojega."},{"v":5,"t":"Poći ću, dakle, velikima i njima ću govoriti, jer oni poznaju put Jahvin i pravo Boga svojega.” Ali oni svi složno razbiše jaram i sve veze pokidaše."},{"v":6,"t":"I zato ih šumski lav napada, vuk pustinjski razdire, leopardi vrebaju gradove njihove, tko god iziđe iz njih bit će rastrgan. Jer su grijesi njihovi mnogobrojni, mnogostruki otpadi njihovi."},{"v":7,"t":"“Zašto da ti oprostim? Sinovi me tvoji napustiše, zaklinju se lažnim bogovima. Ja ih nasitih, oni preljub učiniše, u bludničinu kuću nagrnuše."},{"v":8,"t":"Oni su k'o ugojeni, sileni konji: ržu za ženom bližnjega svoga."},{"v":9,"t":"Pa da to ne kaznim - riječ je Jahvina - narodu takvu da se ne osvetim?"},{"v":10,"t":"Popnite se na zidove! Razarajte! Uništite, ali ne posvema! Iščupajte sve čokote jer nisu Jahvini."},{"v":11,"t":"Da, podlo me izdadoše dom Izraelov i dom Judin” - riječ je Jahvina."},{"v":12,"t":"Zanijekaše Jahvu, rekoše: “Nema ga! Zlo nas neće snaći, nećemo iskusiti ni gladi ni mača!"},{"v":13,"t":"[13a] A proroci su poput vjetra, govornika nema među njima!”"},{"v":14,"t":"Zato ovako govori Jahve, Bog nad Vojskama: “Zato što su tako govorili, [13b] evo što će im se zbiti: U oganj ću pretvoriti svoje riječi u tvojim ustima, a narod ovaj u drvo da ga oganj proždre."},{"v":15,"t":"Evo, dovest ću na vas narod izdaleka, dome Izraelov - riječ je Jahvina. Narod nepobjediv, narod drevan, narod kojega jezik nećeš znati, ni razumjeti što govori."},{"v":16,"t":"Tobolac mu je razjapljen grob. Svi su oni po izboru junaci."},{"v":17,"t":"On će proždrijet' tvoju žetvu, tvoj kruh, sinove i kćeri tvoje, ovce i goveda tvoja, grožđe i smokve tvoje, razorit će ti gradove tvrde u koje se sada uzdaš.”"},{"v":18,"t":"“Ali ni tada - riječ je Jahvina - neću te posve uništiti."},{"v":19,"t":"A kad budu pitali: 'Zašto nam Jahve, Bog naš, učini sve ovo?' ti ćeš im odgovoriti: 'Jer ste mene ostavili da biste služili tuđim bogovima u svojoj zemlji, služit ćete tuđincu u zemlji koja nije vaša!'”"},{"v":20,"t":"“Objavite ovo domu Jakovljevu i obznanite po Judeji:"},{"v":21,"t":"Čujte, dakle, ovo, narode ludi i nerazumni: oči imaju, a ne vide, uši imaju, a ne čuju!"},{"v":22,"t":"Zar se mene nećete bojati - riječ je Jahvina - zar nećete drhtati preda mnom koji sam stavio pijesak moru za granicu, za vječnu među koje nikad neće prijeći: ono se biba, al' je nemoćno, valovi mu huče, ali prijeći neće."},{"v":23,"t":"No, u naroda ovog srce je prkosno, nepokorno; oni se udaljiše - to je snaga njihova!"},{"v":24,"t":"Ne rekoše u srcu svome: 'Bojmo se Jahve, Boga svojega, koji nam u pravi čas šalje dažd rani i kišu kasnu i koji nam čuva tjedne određene za žetvu.'"},{"v":25,"t":"Vaša bezakonja narušiše ovo, vaši vam grijesi uništiše blagostanje."},{"v":26,"t":"Da, u mome narodu ima zlikovaca: kao ptičari vrebaju iz zasjede, postavljaju zamke, hvataju ljude."},{"v":27,"t":"Kao što je krletka puna ptica, tako su njihove kuće pune grabeža; postadoše tako veliki i bogati,"},{"v":28,"t":"tusti i ugojeni. Da, prevršila se mjera zla, ne brane prava, prava sirote ne sreću, ne mare za pravo sirotinje."},{"v":29,"t":"Pa da to ne kaznim - riječ je Jahvina - narodu takvu da se ne osvetim?"},{"v":30,"t":"Strahote i grozote zbivaju se u ovoj zemlji:"},{"v":31,"t":"proroci laž proriču, a svećenici poučavaju na svoju ruku. A mojem narodu to omilje! Al' što ćete raditi na kraju?"}]},"6":{"hr":[{"v":1,"t":"Bježite, sinovi Benjaminovi, isred Jeruzalema! U Tekoi zatrubite u rog, na Bet Hakeremu podignite bojni stijeg! Jer sa Sjevera se nadvija nesreća, propast velika."},{"v":2,"t":"Može li se Kći sionska usporedit' s nježnom tratinom?"},{"v":3,"t":"K njoj dolaze pastiri sa stadima. Svud oko nje razapeše šatore, svaki pase na dijelu svome."},{"v":4,"t":"S njome zametnite sveti boj! Na noge! Navalimo usred dana! Jao nama, jer se dan naginje k zapadu, a večernje sjene duljaju!"},{"v":5,"t":"Na noge! Navalimo usred noći, razrušimo dvore njene!”"},{"v":6,"t":"Jer ovako zbori Jahve nad Vojskama: “Oborite stabla njena, podignite nasip oko Jeruzalema, to je grad laži, u njemu je sve samo tlačenje."},{"v":7,"t":"Kao što iz studenca izvire voda, tako iz njega opačina izvire. U njemu se čuje samo nasilje i pustošenje, preda mnom su svagda bolesti i rane."},{"v":8,"t":"Popravi se, Jeruzaleme, da mi se duša od tebe ne odvrati, da te ne pretvorim u pustoš, u zemlju nenastanjenu.”"},{"v":9,"t":"Ovako govori Jahve nad Vojskama: “Paljetkuj, paljetkuj kao lozu Ostatak Izraelov! Poput berača pruži ruke među čokote!”"},{"v":10,"t":"Komu treba da govorim, koga da opomenem da me saslušaju? Gle, uho im je neobrezano stog ne mogu čuti. Gle, riječ Jahvina postade im porugom, nije im mila."},{"v":11,"t":"Prepun sam gnjeva Jahvina, ne mogu više izdržati! - Izlij ga, dakle, po djeci na ulici i na skupove mladića. Sve će ih obuzeti: muža i ženu, starca i čovjeka zrele dobi."},{"v":12,"t":"Njihove će kuće pripasti drugima, a tako i polja i žene im. “Da, ispružit ću ruku svoju - govori Jahve - na stanovnike ove zemlje,"},{"v":13,"t":"jer od najmanjega do najvećeg svi gramze za plijenom, od proroka do svećenika svi su varalice."},{"v":14,"t":"I olako liječe ranu naroda moga, vičući: 'Mir! Mir!' Ali mira nema."},{"v":15,"t":"Nek' se postide što gnusobu počiniše, no oni više ne znaju što je stid, ne umiju se više crvenjeti. I zato će popadati s onima što padaju, srušit će se kad stanem kažnjavati” - govori Jahve."},{"v":16,"t":"Ovako govori Jahve: “Stanite na negdašnje putove, raspitajte se za iskonske staze: Koji put vodi k dobru? Njime pođite i naći ćete spokoj dušama svojim! Al' oni rekoše: 'Ne idemo!'"},{"v":17,"t":"I postavih im stražare: 'Pazite na glas roga!' Al' oni rekoše: 'Nećemo paziti!'"},{"v":18,"t":"Zato čujte, narodi, i vi pastiri stada njihovih!"},{"v":19,"t":"Čuj, zemljo! Gle, dovodim zlo na ovaj narod, plod njihove pobune, jer oni ne slušahu riječi moje, Zakon moj odbaciše."},{"v":20,"t":"Što će mi tamjan koji dolazi iz Šebe i trska mirisna iz zemlje daleke? Vaše mi paljenice nisu drage, nisu mi po volji klanice vaše.”"},{"v":21,"t":"Zato ovako govori Jahve: “Evo postavljam narodu ovome prepreke o koje će se spotaći, oci i djeca zajedno, poginut će susjed zajedno s prijateljem.”"},{"v":22,"t":"Ovako govori Jahve: “Evo dolazi narod iz zemlje sjeverne, puk velik diže se s krajeva zemlje:"},{"v":23,"t":"u ruci im luk i koplje, okrutni su, nemilosrdni; graja im buči kao more, jašu na konjima, kao jedan za boj spremni protiv tebe, Kćeri sionska."},{"v":24,"t":"Kad saznasmo novost, ruke nam klonuše, strava nas obuze, bol kao porodilju."},{"v":25,"t":"Ne izlazite u polja, ne idite na putove, jer mačevi dušmanski prijete, užas sve uokolo."},{"v":26,"t":"Kćeri mog naroda, kostrijet pripaši, pospi se pepelom, nariči k'o za jedincem tužaljku pregorku. Jer će doći nenadano na nas pustošnik."},{"v":27,"t":"Postavih te za ispitivača naroda mojeg da spoznaš i ispitaš putove njegove."},{"v":28,"t":"Svi su oni odmetnici najgori, okolo kleveću i mjed i željezo, svi su pokvareni."},{"v":29,"t":"Mijeh sopće da bi vatra proždrla olovo, zalud se ljevač trudi da ga rastopi: šljaka se ne da izlučiti.”"},{"v":30,"t":"“Srebro odbačeno”, tako ih zovu, jer ih Jahve odbaci!"}]},"7":{"hr":[{"v":1,"t":"Ovo je riječ što dođe Jeremiji od Gospodina:"},{"v":2,"t":"“Stani pred vrata Doma Jahvina, objavi ondje ovu riječ. Reci: Čujte riječ Jahvinu, svi Judejci koji ulazite na ova vrata da se poklonite Jahvi."},{"v":3,"t":"Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Popravite svoje putove i djela svoja, pa ću boraviti s vama na ovome mjestu."},{"v":4,"t":"Ne uzdajte se u lažne riječi: 'Svetište Jahvino! Svetište Jahvino! Svetište Jahvino!'"},{"v":5,"t":"Ali ako zaista popravite svoje putove i djela svoja i ako zaista budete činili što je pravo, svatko prema bližnjemu svome,"},{"v":6,"t":"ako ne budete tlačili stranca, sirote i udovice i ne budete prolijevali krvi nedužne na ovome mjestu, ako ne budete trčali za tuđim bogovima na svoju nesreću -"},{"v":7,"t":"boravit ću s vama na ovome mjestu, u zemlji koju sam dao vašim ocima zauvijek."},{"v":8,"t":"Ali se vi uzdate u lažne i beskorisne riječi!"},{"v":9,"t":"Zar da kradete, ubijate, činite preljub, krivo se zaklinjete, palite tamjan Baalu i trčite za tuđim bogovima kojih ne poznajete,"},{"v":10,"t":"a onda da dolazite i stojite preda mnom u Domu ovome koji nosi moje ime i govorite: 'Spašeni smo!' i da nakon toga opet činite nedjela i opačine?"},{"v":11,"t":"Zar je Dom ovaj, koji se zove mojim imenom, u vašim očima pećina razbojnička? Ali ja dobro vidim” - riječ je Jahvina."},{"v":12,"t":"“Pođite, dakle, na moje mjesto koje je u Šilu, gdje nekoć nastanih ime svoje, i pogledajte što od njega učinih zbog opačina naroda svoga izraelskoga."},{"v":13,"t":"Kako činite sva ona ista nedjela - riječ je Jahvina - i premda vas neumorno opominjem, vi ne slušate, a kad vas zovem, vi se ne odazivate:"},{"v":14,"t":"od ovoga Doma što se zove mojim imenom, u koje se vi uzdate, i od ovoga mjesta što ga dadoh vama i ocima vašim učinit ću isto što sam učinio i od Šila."},{"v":15,"t":"Odbacit ću vas od lica svojega kao što odbacih svu braću vašu, sve potomstvo Efrajimovo.”"},{"v":16,"t":"“A ti ne moli milosti za narod ovaj, ne diži glasa za njih i ne moli, ne navaljuj na me jer te neću uslišiti."},{"v":17,"t":"Ne vidiš li što čine po gradovima judejskim i po ulicama jeruzalemskim?"},{"v":18,"t":"Djeca kupe drva, oci pale vatru, žene mijese tijesto da ispeku kolače 'kraljici neba' i lijevaju ljevanice tuđim bogovima da me pogrde."},{"v":19,"t":"Zar mene tim pogrđuju - riječ je Jahvina - a ne sebe na svoju sramotu?”"},{"v":20,"t":"I stoga ovako govori Jahve Gospod: “Evo, gnjev svoj i jarost svoju izlit ću na ovo mjesto, na ljude i na stoku, na poljsko drveće i na plodove zemlje, rasplamtjet će se i neće se ugasiti.”"},{"v":21,"t":"Ovako govori Jahve nad Vojskama, Bog Izraelov: “Paljenicama dometnite još i klanice, i jedite meso."},{"v":22,"t":"Ja ništa ne rekoh ocima vašim o paljenicama i klanicama, niti im što o tom zapovjedih kad ih izvedoh iz zemlje egipatske."},{"v":23,"t":"Ovo im ja zapovjedih: 'Slušajte glas moj, pa ću ja biti vaš Bog, a vi ćete biti moj narod. Idite putem kojim vam zapovjedih, da vam dobro bude.'"},{"v":24,"t":"A oni ne poslušaše, uho svoje ne prignuše, već pođoše po savjetu i okorjelosti zloga srca svojega; okrenuše mi leđa, a ne lice."},{"v":25,"t":"Od dana kad oci vaši iziđoše iz zemlje egipatske pa do dana današnjeg slao sam vam tolike sluge svoje, proroke, iz dana u dan, neumorno."},{"v":26,"t":"Ali me oni nisu slušali, uho svoje nisu prignuli, nego otvrdnuše, gori od otaca svojih."},{"v":27,"t":"Možeš im sve to reći, ali te neće poslušati; zovi ih, neće ti se odazvati."},{"v":28,"t":"Zato im reci: 'Ovo je narod koji ne sluša glasa Jahve, Boga svojega, i ne prima opomenÄe. Nestade istine, nestade je iz usta njihovih.'”"},{"v":29,"t":"Ostriži svoju dugu kosu, baci je. Po goletima protuži tužaljkom, jer Jahve odbaci i odvrgnu rod na koji se razgnjevio."},{"v":30,"t":"“Da, sinovi Judini čine što je zlo u očima mojim” - riječ je Jahvina. “Postaviše grozote u Dom koji se mojim zove imenom, da ga oskvrnu;"},{"v":31,"t":"podigoše uzvišice tofetske u Dolini Ben Hinomu i spaljuju vatrom svoje sinove i kćeri - što im ja nikad ne zapovjedih niti mi to ikada na um pade."},{"v":32,"t":"Stoga evo dolaze dani - riječ je Jahvina - kad se više neće reći Tofet ni Dolina Ben Hinom, nego Dolina klanja. U Tofetu će se pokapati mrtvi, jer drugdje neće biti mjesta."},{"v":33,"t":"A mrtva tijela ovoga naroda bit će hrana pticama nebeskim i zvjeradi zemaljskoj, i nitko se neće naći da ih poplaši i otjera."},{"v":34,"t":"Uklonit ću iz gradova judejskih i s ulica jeruzalemskih radost i veselje: jer će se zemlja ta pretvoriti u pustinju.”"}]},"8":{"hr":[{"v":1,"t":"“U ono vrijeme - riječ je Jahvina - povadit će iz grobova kosti kraljeva judejskih, kosti knezova njezinih, kosti svećenika, kosti proroka i kosti žitelja jeruzalemskih."},{"v":2,"t":"I razasut će ih prema suncu, prema mjesecu i prema svoj vojsci nebeskoj, koje ljubljahu, kojima služahu, koje slijeđahu, koje za savjet pitahu i kojima se klanjahu. I neće ih pokupiti i sahraniti; ostat će kao gnoj po zemlji."},{"v":3,"t":"Tada će svima onima što preostanu od tih zlih plemena, po svim mjestima kuda ih rasprših, smrt biti milija od života” - riječ je Jahve nad Vojskama."},{"v":4,"t":"“Reci im: Ovako govori Jahve: 'Padne li tko, neće li opet ustati, zaluta li, neće li se opet vratiti?"},{"v":5,"t":"Zašto onda taj narod luta uporno i neprekidno? Čvrsto se drže laži, neće da se obrate."},{"v":6,"t":"Pazio sam i osluškivao: Ne govore kako valja. Nitko se ne kaje zbog pakosti svoje, i ne govori 'Što učinih?' Svatko je skrenuo trku svoju kao konj kad u boj nagne."},{"v":7,"t":"Čak i roda pod nebom zna svoje vrijeme, grlica, lastavica i ždral drže se vremena kad se moraju vratiti. A moj narod ne poznaje suda Jahvina."},{"v":8,"t":"Kako možete tvrditi: 'Mi smo mudri, u nas je Zakon Jahvin!' Zaista, u laž ga je pretvorila lažljiva pisaljka pisara!"},{"v":9,"t":"Mudraci će biti osramoćeni, prestravljeni i uhvaćeni u zamku. Gle, oni prezreše riječ Jahvinu! A njihova mudrost - što im koristi?"},{"v":10,"t":"Zato ću žene njihove dati strancima, a vaša polja osvajačima. Jer od najmanjeg do najvećega svi gramze za plijenom, od proroka do svećenika svi su varalice."},{"v":11,"t":"I olako liječe ranu naroda mojega vičući: 'Mir! Mir!' Ali mira nema."},{"v":12,"t":"Neka se postide što gnusobu počiniše, no oni više ne znaju što je stid, ne umiju se više crvenjeti. Zato će popadati s onima što padaju, srušit će se kad stanem kažnjavati” - govori Jahve."},{"v":13,"t":"“Htjedoh u berbu k njima - riječ je Jahvina - a ono ni grozda na trsu, ni smokve na smokvi; čak je i lišće uvelo. Zato ih predah onima što prolaze kraj njih."},{"v":14,"t":"'Zašto još čekamo? Na okup! Zavucimo se u tvrde gradove da ondje izginemo, jer nas Jahve, Bog naš, zatire, napaja nas vodom otrovanom, jer zgriješismo protiv Jahve."},{"v":15,"t":"Nadasmo se miru, ali dobra nema, čekasmo vrijeme ozdravljenja, al' evo užasa!"},{"v":16,"t":"Iz Dana dopire njištanje konja njegovih, od rzanja njegovih pastuha dršće zemlja sva. Dolaze da proždru zemlju i što je napunja, grad i žitelje u njemu.'"},{"v":17,"t":"I gle, puštam na vas otrovnice protiv kojih nema čarolija; ujedat će vas - riječ je Jahvina -"},{"v":18,"t":"lijeka biti neće.” Bol me spopada, srce mi iznemoglo."},{"v":19,"t":"Evo zapomažu kćeri naroda moga iz zemlje daleke: “Zar Jahve nije više na Sionu? Kralj njegov? Zašto me razjariše svojim kipovima, ništavilima tuđinskim?"},{"v":20,"t":"Žetva prođe, minu ljeto, a mi nismo spašeni!”"},{"v":21,"t":"Satrven sam što je kći naroda mojega satrvena, žalostan sam, stravom obuzet."},{"v":22,"t":"Zar u Gileadu nema balzama? Nema li ondje liječnika? TÓa zašto ne dolazi ozdravljenje kćeri naroda mojega?"},{"v":23,"t":"O, tko bi glavu moju pretvorio u vrelo, a oči moje u vrutak suza, danju i noću da plačem nad poginulima kćeri svoje, naroda svojega!"}]},"9":{"hr":[{"v":1,"t":"“Da imam u pustinji obitavalište, ostavio bih narod svoj i daleko od njih otišao. Jer svi su oni preljubnici, rulja izdajnička."},{"v":2,"t":"Kao luk napinju jezik, laž, a ne istina, prevladava na zemlji. Iz zla u zlo srljaju, mene ne poznaju” - riječ je Jahvina!"},{"v":3,"t":"“Nek se svatko čuva prijatelja, a brat bratu neka ne vjeruje, jer brat svaki nasljeduje Jakova, a svaki prijatelj raznosi klevete."},{"v":4,"t":"Jedan drugoga varaju, istine ne govore, privikoše jezik da govori laži; izopačeni, ne mogu se više"},{"v":5,"t":"vratiti. Nasilje na nasilje! Prijevara za prijevarom! Neće da spoznaju mene” - riječ je Jahvina."},{"v":6,"t":"Stog ovako govori Jahve nad Vojskama: “Evo, pretopit ću ih i ispitati, tÓa kako da i postupaju prema kćeri naroda moga?"},{"v":7,"t":"Jezik im je strijela ubojita, na ustima riječ prijevarna. 'Mir s tobom', pozdravljaju bližnjega, ali mu u srcu zamku spremaju."},{"v":8,"t":"Pa da ih zbog toga ne kaznim - riječ je Jahvina - narodu takvu da se ne osvetim?”"},{"v":9,"t":"“Zaplačite, tugujte nad brdima, nad ispašama pustinjskim naričite! Jer izgorješe, nitko ne prolazi, glas stada više se ne čuje. Od ptice nebeske do stoke sve pobježe, svega nestade."},{"v":10,"t":"Od Jeruzalema učinit ću gomilu kamenja, brlog čagaljski, gradove judejske pretvorit ću u pustoš gdje nitko ne stanuje.”"},{"v":11,"t":"Tko je mudar da bi to razumio, kome su usta Jahvina govorila da objavi zašto zemlja izgorje kao pustinja i nitko njome više ne prolazi?"},{"v":12,"t":"I reče Jahve: “Jer ostaviše Zakon moj koji im dadoh i jer ne slušahu glasa mojega, niti ga slijeđahu,"},{"v":13,"t":"nego slijeđahu okorjelo srce svoje i baale kojima ih oci njihovi naučiše,"},{"v":14,"t":"ovako govori Jahve nad Vojskama, Bog Izraelov: Evo, nahranit ću narod ovaj pelinom i napojiti ga vodom zatrovanom."},{"v":15,"t":"I raspršit ću ih među narode kojih ne poznavahu oni ni oci njihovi. A za njima ću poslati mač da ih zatre.” Ovako govori Jahve nad Vojskama:"},{"v":16,"t":"“Pazite! Pozovite narikače! Neka dođu! Pošaljite po najvještije! Neka dođu!"},{"v":17,"t":"Neka pohite da zapjevaju tužbalicu nad nama! Da suze poteku iz očiju naših, da voda poteče s trepavica naših!"},{"v":18,"t":"Sa Siona dopire tužbalica: 'O, kako smo upropašteni, osramoćeni veoma! Jer moramo zemlju ostaviti i stanove svoje napustiti.'”"},{"v":19,"t":"I zato, o žene, čujte riječ Jahvinu, i neka uho vaše primi riječ iz usta njegovih. Učite kćeri svoje jadati, jedna drugu naricati:"},{"v":20,"t":"“Smrt se ušulja kroz prozore naše, uđe u dvore naše, djecu pokosi nasred ulice, mladiće nasred trgova."},{"v":21,"t":"I mrtva tjelesa leže kao gnoj po oranicama, kao snoplje za žeteocem, a nikoga da ih skupi.”"},{"v":22,"t":"Ovako govori Jahve: “Mudri neka se ne hvale mudrošću, ni junak neka se ne hvali hrabrošću, ni bogati neka se ne hvali bogatstvom."},{"v":23,"t":"A tko se hvaliti hoće, neka se hvali time što ima mudrost da mene spozna. Jer ja sam Jahve koji tvori dobrotu, pravo i pravdu na zemlji, jer to mi je milo” - riječ je Jahvina."},{"v":24,"t":"“Evo, bliže se dani” - riječ je Jahvina - “kaznit ću sve koji su obrezani na tijelu:"},{"v":25,"t":"Egipat, Judeju, Edom, sinove Amonove i Moab i sve one što briju zaliske i prebivaju u pustinji. Jer svi su ti narodi neobrezani i sav dom Izraelov neobrezana je srca!”"}]},"10":{"hr":[{"v":1,"t":"Slušajte riječ koju vam govori Jahve, dome Izraelov."},{"v":2,"t":"Ovako govori Jahve: “Ne privikavajte se putu bezbožnom i ne dršćite pred znacima nebeskim, jer pred njima dršću samo bezbošci."},{"v":3,"t":"Jer su strašila tih naroda puka ništavnost, samo drvo posječeno u šumi, djelo ruku tesarovih,"},{"v":4,"t":"ukrašeno srebrom i zlatom, pričvršćeno čavlima i čekićima da se ne klima."},{"v":5,"t":"Nalik su na ptičja strašila u vrtu: ne znaju govoriti. Treba ih nositi, jer ne umiju hodati. Njih se ne bojte, jer ne mogu zla činiti, ali ni dobra učiniti ne mogu.”"},{"v":6,"t":"Nitko nije kao ti, Jahve, ti si velik i silno je ime tvoje."},{"v":7,"t":"Tko da se tebe ne boji, kralju naroda? Zaista, tebi to pripada, jer među svim mudracima naroda i u svim njihovim kraljevstvima tebi nema ravna!"},{"v":8,"t":"Čime vatru lože, to ih zaluđuje! Zakon im isprazan - obično drvo,"},{"v":9,"t":"tankolisto srebro dovezeno iz Taršiša, zlato iz Ofira, rad kipara i rukotvorina zlatara, sva djela umješna, ogrnuta ljubičastim i crvenim grimizom."},{"v":10,"t":"A Jahve je pravi Bog. Živi je on Bog i Kralj vječni. Od njegova gnjeva zemlja se trese. Narodi ne mogu podnijeti jarosti njegove."},{"v":11,"t":"Evo što ćete o kipovima reći: “Bogovi koji nisu stvorili neba ni zemlje moraju nestati s lica zemlje i ispod neba.”"},{"v":12,"t":"On stvori zemlju snagom svojom, mudrošću svojom uspostavi krug zemaljski i umom svojim razape nebesa."},{"v":13,"t":"Kad mu glas zaori, huče vode na nebesima, oblake diže s kraja zemlje; stvara kiši munje, vjetar izvodi iz skrovišta njegovih."},{"v":14,"t":"Svakom čovjeku pamet stane, svaki se zlatar zastidi svoga kipa, jer svi su mu kipovi samo varka, nema u njima duha!"},{"v":15,"t":"Isprazni su oni, smiješne tvorevine, propast će u dan kazne."},{"v":16,"t":"'Jakovljev dio' nije kao oni: jer je on sve stvorio, Izrael pleme je baštine njegove, Jahve nad Vojskama ime je njegovo.”"},{"v":17,"t":"Skupi prnje svoje sa zemlje, ti koja stanuješ u utvrdi!"},{"v":18,"t":"Jer ovako govori Gospod: “Gle, ovaj put daleko ću odbaciti stanovnike ove zemlje, pritijesniti ih da me nađu.”"},{"v":19,"t":"“Jao meni zbog ozljede moje, rana je moja neiscjeljiva.” A ja rekoh: “Ipak, bolest je moja, nosit ću je!"},{"v":20,"t":"Šator je moj obÄaljen, sva užeta pokidana. Djeca me ostaviše: nema ih. Nema ga tko bi opet razapeo šator moj i podigao krila šatorska.”"},{"v":21,"t":"Da, pastiri pamet izgubiše: ne tražiše Jahve. Zato ih sreća ne prati i sva se stada raspršiše."},{"v":22,"t":"Čujte vijest! Primiče se, evo, buka strašna iz zemlje sjeverne, da gradove judejske pretvori u pustinju, u brlog čagalja."},{"v":23,"t":"Znam, Jahve, da put čovjeka nije u njegovoj vlasti, da čovjek koji hodi ne može upravljati korake svoje!"},{"v":24,"t":"Kazni me, Jahve, ali po pravici, ne u gnjevu, da nas ne zatreš."},{"v":25,"t":"Izlij gnjev na narode koji te ne priznaju i na plemena koja ne zazivlju imena tvoga! Jer oni su proždrli Jakova, izjeli ga, opustošili naselje njegovo."}]},"11":{"hr":[{"v":1,"t":"Riječ koju je Jahve uputio Jeremiji:"},{"v":2,"t":"“Govori Judejcima i Jeruzalemcima."},{"v":3,"t":"Reci im: Ovako veli Jahve, Bog Izraelov: 'Proklet bio čovjek koji ne posluša riječi Saveza ovoga,"},{"v":4,"t":"riječi koje sam zapovjedio ocima vašim kad sam ih izveo iz zemlje egipatske, iz one peći ražarene, govoreći: Poslušajte glas moj i činite sve što vam zapovjedim: tada ćete biti narod moj, a ja vaš Bog,"},{"v":5,"t":"da bih ispunio zakletvu kojom sam se zakleo ocima vašim da ću im dati zemlju u kojoj teče mlijeko i med - kao što je danas.'” A ja odgovorih i rekoh: “Tako je, Jahve.”"},{"v":6,"t":"I dalje mi reče Jahve: “Objavi riječi ove po gradovima judejskim i po ulicama jeruzalemskim: 'Poslušajte riječi Saveza ovoga, te ih izvršavajte."},{"v":7,"t":"Jer sam ozbiljno opominjao očeve vaše kad sam ih izvodio iz zemlje egipatske i do danas ih neumorno opominjem: Poslušajte glas moj!"},{"v":8,"t":"Ali oni ne slušahu i ne prignuše uha svojega, nego se povedoše za okorjelošću zloga srca svoga. Zato dopustih da se na njima ispune sve riječi Saveza ovoga za koji im zapovjedih da ga se pridržavaju, ali ga se oni ne pridržavahu.'”"},{"v":9,"t":"I reče mi Jahve: “Zavjera je među Judejcima i Jeruzalemcima."},{"v":10,"t":"Vratiše se bezakonjima svojih otaca koji se oglušiše na moje riječi, pa trčahu za tuđim bogovima da im služe. Dom Izraelov i dom Judin prekršiše Savez moj koji sam sklopio s ocima njihovim.”"},{"v":11,"t":"Zato ovako govori Jahve: “Evo, dovest ću na njih zlo kojemu neće umaći; vapit će k meni, ali ih ja neću slušati."},{"v":12,"t":"Onda neka gradovi judejski i žitelji jeruzalemski vapiju k bogovima kojima kade, ali im oni neće pomoći u vrijeme nevolje!"},{"v":13,"t":"Jer imaš, o Judejo, bogova koliko i gradova! I koliko ima ulica u Jeruzalemu, toliko žrtvenika podigoste da kadite Baalu."},{"v":14,"t":"Ti, dakle, ne moli milosti za taj narod, ne diži glasa za njih i ne moli, jer ih neću uslišiti kad me zazovu u nevolji svojoj.”"},{"v":15,"t":"Što li će draga moja u Domu mome? Kuje zle osnove. Hoće li pretilina i meso posvećeno ukloniti zlo od tebe? Mogu li te stoga proglasiti čistom?"},{"v":16,"t":"“Zelena maslina lijepa uzrasta”, tako te Jahve nazva. A sada uz prasak veliki plamenom sažiže njeno lišće; spaljene su grane njene."},{"v":17,"t":"Jahve nad Vojskama, koji te bijaše posadio, nesreću ti namijeni zbog zločina što ga učini dom Izraelov i dom Judin kadeći Baalu da bi mene razgnjevili."},{"v":18,"t":"Jahve mi objavi te znam! Tada mi ti, Jahve, razotkri njihove spletke."},{"v":19,"t":"A ja bijah kao jagnje krotko što ga vode na klanje i ne slutih da protiv mene snuju pakosne naume. “Uništimo drvo još snažno, iskorijenimo ga iz zemlje živih, da mu se ime nikad više ne spominje!”"},{"v":20,"t":"Ali ti, Jahve nad Vojskama, koji pravedno sudiš, koji ispituješ srca i bubrege, daj da vidim kako se njima osvećuješ, jer tebi povjerih parnicu svoju."},{"v":21,"t":"Zato Jahve nad Vojskama govori protiv ljudi u Anatotu koji mi rade o glavi i govore: “Ne prorokuj više u ime Jahvino, da ne pogineš od ruke naše!”"},{"v":22,"t":"Ovako govori Jahve nad Vojskama: “Evo, ja ću ih kazniti. Njihovi će mladići od mača poginuti, sinovi i kćeri pomrijet će od gladi."},{"v":23,"t":"Ni ostatka neće ostati kad donesem nesreću ljudima u Anatotu u godini kazne njihove.”"}]},"12":{"hr":[{"v":1,"t":"Prepravedan si, Jahve, da bih se mogao s tobom parbiti. Samo bih jedno s tobom raspravio: Zašto je put zlikovaca uspješan? Zašto podmuklice uživaju mir?"},{"v":2,"t":"Ti si ih posadio, i oni se ukorijeniše, rastu i plod donose. Al' si bliz samo ustima njihovim, a daleko im od srca."},{"v":3,"t":"No ti, Jahve, mene poznaješ i vidiš; ispitao si srce moje, ono je s tobom. Odvedi ih kao jagnjad na klanje, sačuvaj ih za dan pokolja."},{"v":4,"t":"Dokle će zemlja tugovati, dokle će trava na svem polju sahnuti? Zbog opačine njezinih stanovnika ugiba stoka i ptice! Jer govore: Bog ne vidi naših putova."},{"v":5,"t":"Ako s pješacima trčeći sustaješ, kako ćeš se s konjima utrkivati? Kad ni u mirnoj zemlji nemaš uzdanja, kako ćeš onda kroz guštare jordanske?"},{"v":6,"t":"Jer su i braća tvoja i obitelj tvoja licemjerni prema tebi! I oni te iza leđa ocrnjuju na sva usta. Ne vjeruj im kad ti zbore umilno."},{"v":7,"t":"Ostavih dom svoj, napustih baštinu svoju; miljenicu srca svoga dadoh u ruke dušmana njenih."},{"v":8,"t":"Baština moja postade za me kao lav u šumi. Zarikao je na me, zato ga zamrzih."},{"v":9,"t":"Zar je baština moja šarena ptica oko koje odasvud druge slijeću? Hajde, skupite se, sve divlje zvijeri, dođite žderati."},{"v":10,"t":"Mnogi pastiri opustošiše moj vinograd, zgaziše nasljedstvo moje; dragu mi baštinu pretvoriše u golu pustinju,"},{"v":11,"t":"pretvoriše u pustoš, žalosna je pustoš preda mnom. Sva je zemlja pusta jer nikog u srce ne dira."},{"v":12,"t":"Preko svih goleti pustinjskih nagrnuše pustošnici. Jer u Jahve je mač što proždire: s jednog kraja zemlje do drugog nema mira nijednome tijelu."},{"v":13,"t":"Sijahu pšenicu, a požeše trnje: iscrpli se bez koristi. Stide se uroda svoga sve zbog jarosti Jahvine."},{"v":14,"t":"Ovako govori Jahve: “Sve zle susjede svoje, koji su dirnuli u baštinu što sam je dao narodu svome Izraelu, ja ću iščupati iz zemlje njihove. Ali dom Judin iščupat ću isred njih."},{"v":15,"t":"A kad ih iščupam, ponovo ću im se smilovati i povesti natrag, svakoga na baštinu i zemlju njegovu."},{"v":16,"t":"Pa ako doista nauče putove naroda mojega i stanu se zaklinjati imenom mojim - 'Živoga mi Jahve' - kao što su učili moj narod da se zaklinje Baalom, tada će se opet nastaniti usred naroda moga."},{"v":17,"t":"Ako pak ne poslušaju, onda ću takav narod potpuno iščupati i zatrti” - riječ je Jahvina."}]},"13":{"hr":[{"v":1,"t":"Ovako mi govori Jahve: “Idi i kupi sebi lanen pojas i opaši bokove. Ali ga u vodu ne umači.”"},{"v":2,"t":"I kupih pojas po riječi Jahvinoj i opasah bokove."},{"v":3,"t":"I dođe mi drugi put riječ Jahvina:"},{"v":4,"t":"“Uzmi pojas što si ga kupio i njime se opasao, digni se, idi do rijeke Eufrata i sakrij ga ondje u pukotinu pećine.”"},{"v":5,"t":"I odoh i sakrih ga kraj Eufrata, kako mi Jahve zapovjedi. Poslije mnogo dana reče mi Jahve:"},{"v":6,"t":"“Ustaj, idi na Eufrat pa izvuci odande pojas za koji ti zapovjedih da ga ondje sakriješ.”"},{"v":7,"t":"Odoh na Eufrat, izvukoh i uzeh pojas s mjesta gdje ga bijah sakrio, i gle: pojas istrunuo, ne bijaše više nizašto."},{"v":8,"t":"Tada mi dođe riječ Jahvina:"},{"v":9,"t":"“Ovako govori Jahve: Tako ću uništiti silnu oholost Judeje i Jeruzalema."},{"v":10,"t":"Narod taj opaki koji ne sluša mojih riječi, nego slijedi okorjelo srce svoje i trči za drugim bogovima da im služi i da im se klanja, postat će kao tvoj pojas koji nije više nizašto."},{"v":11,"t":"Jer kao što pojas prianja uz bedra čovjekova, tako sam htio da sav dom Izraelov i sav dom Judin prianja uza me - riječ je Jahvina - da budu moj narod, moj dobar glas, moj ponos, moja slava i čast. Ali nisu poslušali!”"},{"v":12,"t":"Reci tom narodu: “Svaki se vrč puni vinom.” A oni će ti prigovoriti: “Zar možda ne znamo da se svaki vrč puni vinom?”"},{"v":13,"t":"Reci im tada: “Ovako govori Jahve: evo, napunit ću pijanošću sve stanovnike ove zemlje, kraljeve što sjede na prijestolju Davidovu, i svećenike, i proroke, i sve Jeruzalemce."},{"v":14,"t":"I porazbijat ću ih jednog o drugoga, očeve zajedno sa sinovima - riječ je Jahvina. Uništit ću ih bez samilosti, bez milosrđa i bez smilovanja.”"},{"v":15,"t":"Poslušajte, dobro čujte, okanite se oholosti: Jahve sad govori!"},{"v":16,"t":"Dajte slavu Jahvi, Bogu svojemu, prije nego što se smrkne, prije nego što se noge vaše spotaknu po planinama mračnim. Vi se nadate svjetlosti, a on će je u mrak pretvoriti, prometnuti u crnu tamu!"},{"v":17,"t":"Ako ovo ne poslušate, potajno će mi duša plakati zbog oholosti vaše, suze će roniti, oko će mi suze prolijevati, jer Jahvino stado u izgnanstvo odlazi."},{"v":18,"t":"Reci kralju i kraljici-majci: “Sjednite duboko dolje, jer vijenac slave pade s vaših glava."},{"v":19,"t":"Gradovi Negeba zatvoreni su, i nikoga nema da ih otvori. Sva je Judeja izgnana, sasvim izgnana!”"},{"v":20,"t":"Podigni oči, Jeruzaleme, i pogledaj one što nadiru sa Sjevera. Gdje je stado tebi povjereno, slavne ovce tvoje?"},{"v":21,"t":"Što ćeš reći kada ti se nametnu kao gospodari tvoji oni koje si sam naučio da te kao ljubavnici vode. Neće li te bolovi spopasti kao porodilju?"},{"v":22,"t":"Možda ćeš se tad upitati: “Zašto me to snašlo?” Zbog mnoštva bezakonja tvojih otkriše ti skute, nasilje nad tobom učiniše."},{"v":23,"t":"Može li Etiopljanin promijeniti kožu svoju? Ili leopard krzno svoje? “A vi, možete li činiti dobro, navikli da zlo činite?"},{"v":24,"t":"Zato ću vas raspršiti k'o pljevu koju raznosi pustinjski vjetar."},{"v":25,"t":"To je sudba tvoja i dio tebi odmjeren - riječ je Jahvina - jer si mene zaboravio i u laž se uzdao."},{"v":26,"t":"Sam ću ti halju do lica podići da se tvoja golotinja vidi."},{"v":27,"t":"Sve preljube tvoje, tvoje vriskanje i bestidno tvoje bludničenje, na humcima, u poljima, vidio sam tvoje grozote. Jao tebi, Jeruzaleme! Još se ne očisti i dokle će to još trajati ...?”"}]},"14":{"hr":[{"v":1,"t":"Riječ Jahvina Jeremiji o velikoj suši:"},{"v":2,"t":"Judeja je tugom obrvana i ginu njeni gradovi, sumorno leže na zemlji, krik Jeruzalema do neba se vije."},{"v":3,"t":"Odličnici šalju sluge po vodu: dolaze do studenaca, ali vode ne nalaze, vraćaju se praznih vrčeva, postiđeni, posramljeni, pokriše glavu svoju."},{"v":4,"t":"Zemlja je sva ispucala jer kiše nema. Ratari se postidješe, pokriše glave."},{"v":5,"t":"Pa i košuta u polju ostavlja mlado jer trave nema."},{"v":6,"t":"Divlji magarci, stojeć' na goletima, dašću kao čagalj, oči im malaksale jer nema zelenila."},{"v":7,"t":"Bezakonja naša protiv nas svjedoče, smiluj se, o Jahve, rad' imena svoga! Jer otpadosmo od tebe, tebi sagriješismo,"},{"v":8,"t":"o nado Izraelova, spasitelju njegov u danima nevolje! Zašto si kao stranac u ovoj zemlji, kao putnik što se uvrati da prenoći?"},{"v":9,"t":"Zašto si kao prestravljen čovjek, kao junak koji ne može pomoći? TÓa ti si među nama, o Jahve, mi se tvojim zovemo imenom - nemoj nas ostaviti!"},{"v":10,"t":"Ovako govori Jahve o narodu ovome: Jest, oni vole tumarati i ne štede svojih nogu, i zato ih Jahve ne voli. I sada se spominje bezakonja njihova i kažnjava grijehe njihove."},{"v":11,"t":"I reče mi Jahve: “Ne traži milosti za ovaj narod."},{"v":12,"t":"Ako će i postiti, neću uslišiti njihovih vapaja. Ako će i prinijeti paljenicu i prinos, neće mi omiljeti. Jer mačem, glađu i kugom ja ću ih zatrti.”"},{"v":13,"t":"Tada rekoh: “Ah, Jahve Gospode! Eno, proroci im govore: 'Nećete vidjeti mača, niti će vam biti gladi, nego ću vam dati postojan mir na ovome mjestu.'”"},{"v":14,"t":"A Jahve mi reče: “Laž prorokuju ti proroci u moje ime; niti ih poslah niti im nalog kakav dadoh - ja im i nisam govorio. Oni vam prorokuju lažna viđenja, isprazna gatanja i snove srca svoga.”"},{"v":15,"t":"Zato ovako govori Jahve: “Proroci ti što u moje ime prorokuju, a ja ih nisam poslao, te govore da neće biti ni mača ni gladi u zemlji ovoj, sami će od mača i gladi poginuti."},{"v":16,"t":"A narod ovaj kojemu prorokuju ležat će po ulicama jeruzalemskim, pokošen mačem i glađu, i neće biti čovjeka da ga pokopa - njih, žene njihove, sinove i kćeri njihove. Tako ću na njih izliti zloću njihovu.”"},{"v":17,"t":"A ti im reci ovako: Nek' oči moje suze rone danju i noću, i neka ne prestanu, jer je strašno slomljena djevica, kći naroda moga, ranom neobično ljutom."},{"v":18,"t":"Pođem li u polje, evo mačem pobijenih! Vratim li se u grad, evo od gladi iznemoglih! Čak i proroci i svećenici lutaju po zemlji i ništa ne znaju."},{"v":19,"t":"TÓa zar si Judeju sasvim odbacio? Zar ti duši omrznu Sion? Zašto nas tako biješ te nam više nema lijeka? Nadasmo se miru, ali dobra nema, čekasmo vrijeme ozdravljenja, al' evo užasa!"},{"v":20,"t":"O Jahve, bezbožnost svoju priznajemo, bezakonje otaca svojih; doista, tebi sagriješismo!"},{"v":21,"t":"Ne odbaci nas, rad' imena svoga, ne sramoti prijesto Slave svoje, spomeni se i nemoj razvrći Saveza svog s nama!"},{"v":22,"t":"Zar ispraznost bezbožnika dažda daje? Ili zar nebesa sama kiše? Zar ne daješ ti to, Jahve, Bože naš? Zato se u te uzdamo, jer ti sve to činiš."}]},"15":{"hr":[{"v":1,"t":"I reče mi Jahve: “Kad bi i Mojsije i Samuel stali pred lice moje, ne bi mi se duša obratila narodu tome. Otjeraj ih ispred lice mojega, neka idu od mene!"},{"v":2,"t":"Ako te upitaju: 'Kamo da idemo?' odgovori im: 'Ovako govori Jahve: Tko je za smrt, u smrt! Tko je za mač, pod mač! Tko je za glad, u glad! Tko je za izgnanstvo, u izgnanstvo!'"},{"v":3,"t":"Poslat ću na njih četiri nevolje - riječ je Jahvina: mač da ih ubija, pse da ih rastrgaju, ptice nebeske i zvjerad da ih žderu i zatiru."},{"v":4,"t":"I učinit ću ih užasom svim kraljevstvima zemaljskim, i to zbog Manašea, sina Ezekijina, kralja judejskoga - za sva zla što ih počini u Jeruzalemu.”"},{"v":5,"t":"“Tko da se smiluje tebi, Jeruzaleme, tko da te požali? Tko li će se svratit' da te zapita kako ti je?"},{"v":6,"t":"Ti me odbaci - riječ je Jahvina - i leđa mi okrenu. I zato na te digoh ruku zatornicu. Dojadi mi da ti uvijek praštam!"},{"v":7,"t":"Zato ću ih izvijati vijačom na vratima zemlje ove. Narod svoj ću lišit' djece i istrijebit' ga, jer se ne obraćaju sa svojih putova."},{"v":8,"t":"Bit će u njih više udovica negoli pijeska morskoga. Na majke mladih ratnika dovest ću zatornika, usred podneva, i pustit ću na njih iznenada užas i strahotu."},{"v":9,"t":"Onesvijestila se roditeljka sedmero djece, dušu ispustila. Sunce joj zađe još za dana: postiđena, osramoćena je. A što od njih ostane, pod mač ću vrći pred njihovim dušmanima” - riječ je Jahvina."},{"v":10,"t":"Jao meni, majko, što si me rodila, da svađam se i prepirem sa svom zemljom. Nikom ne uzajmih, ni od koga zajma ne uzeh, a ipak svi me proklinju."},{"v":11,"t":"Uistinu, o Jahve, nisam li ti služio za njihovo dobro, nisam li tražio milost u tebe za neprijatelja svoga, u doba nevolje, u danima tjeskobe njegove? Ti to dobro znaš!"},{"v":12,"t":"Može l' se željezo slomiti, željezo sa Sjevera i mjed?"},{"v":13,"t":"Tvoje bogatstvo i blago tvoje pljački ću predati. Tako ćeš platiti za sva bezakonja svoja po svoj zemlji."},{"v":14,"t":"Učinit ću te robljem neprijatelja u zemlji koju ne poznaješ, jer gnjev moj planu ognjem koji će vas sažgati, koji će protiv vas buknuti."},{"v":15,"t":"Jahve, spomeni me se i pohodi me i kazni progonitelje moje. Ne daj da propadnem zbog sporosti srdžbe tvoje! Spomeni se da tebe radi podnosim sramotu."},{"v":16,"t":"Kad mi dođoše riječi tvoje, ja sam ih gutao: riječi tvoje ushitiše i obradovaše srce moje. Jer sam se tvojim zvao imenom, o Jahve, Bože nad Vojskama."},{"v":17,"t":"Nikad sjedio nisam u društvu veseljaka da se razveselim. Pod težinom ruke tvoje samotan živim, jer ti me jarošću prože."},{"v":18,"t":"Zašto je bol moja bez prebola? Zašto je rana moja neiscjeljiva i nikako da zaraste? Ah! Hoćeš li meni biti kao potok nestalan, vodama nepouzdan?"},{"v":19,"t":"Zato ovako govori Jahve: “Ako se vratiš, pustit ću te da mi opet služiš; ako odvojiš dragocjeno od bezvrijedna, bit ćeš usta moja. Oni će se okrenuti k tebi, al' ti se zato ne smiješ okrenuti k njima!"},{"v":20,"t":"Učinit ću od tebe za ovaj narod zid od mjedi, neosvojiv. Borit će se protiv tebe, al' te neće nadvladati, jer ja sam s tobom, da te spasim i izbavim” - riječ je Jahvina."},{"v":21,"t":"“Izbavit ću te iz ruku zlikovaca i otkupiti te iz ruku silnika.”"}]},"16":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina i reče:"},{"v":2,"t":"“Ne uzimaj sebi žene; i nemaj ni sinova ni kćeri na ovome mjestu."},{"v":3,"t":"Jer ovako govori Jahve o kćerima i sinovima koji će se roditi na ovome mjestu i o majkama koje će ih rađati i o očevima koji će ih imati u ovoj zemlji:"},{"v":4,"t":"Oni će umrijeti smrću prebolnom, nitko ih neće oplakivati, niti će ih sahraniti. Pretvorit će se u gnoj za oranice, izginut će od mača i gladi, a njihova će trupla biti hrana pticama nebeskim i zvijerima zemaljskim.”"},{"v":5,"t":"Da, ovako govori Jahve: “Ne smiješ ući u kuću žalosti, ne idi naricati niti ih sažaljevati. Jer ja sam tom narodu uskratio mir svoj - riječ je Jahvina - ljubav i samilost."},{"v":6,"t":"Pomrijet će veliko i malo u ovoj zemlji i nitko ih neće pokopati. Nitko neće naricati nad njima, niti će zbog njih praviti ureza, niti kose šišati."},{"v":7,"t":"Za onog u žalosti neće kruh lomiti, da ga utješe zbog pokojnika, nitiće mu tko pružiti pehar utjehe zbog smrti njegova oca ili majke njegove."},{"v":8,"t":"Ne ulazi u kuću slavlja da s njima sjediš i gostiš se.”"},{"v":9,"t":"Jer ovako govori Jahve nad Vojskama, Bog Izraelov: “Evo, učinit ću da s ovog mjesta i pred vašim očima i u ovim danima iščeznu poklici radosti i veselja i glasovi zaručnika i zaručnice."},{"v":10,"t":"A kad objaviš tom narodu sve ove riječi, pa te upitaju: 'Zašto nam Jahve zaprijeti svom ovom golemom nesrećom; u čemu je zločinstvo naše i u čemu su grijesi naši što ih počinismo protiv Jahve, Boga našega?' -"},{"v":11,"t":"onda im odgovori: 'U tom što me ostaviše oci vaši - riječ je Jahvina - i trčaše za tuđim bogovima da im služe i da im se klanjaju, a mene ostaviše i Zakona se moga ne držaše."},{"v":12,"t":"A vi još gore učiniste nego oci vaši, jer evo, svaki se povodi za okorjelošću zloga srca svoga, a mene ne sluša."},{"v":13,"t":"Zato ću vas istjerati iz ove zemlje u zemlju koja vam je neznana, kao što bijaše i ocima vašim. Ondje ćete služiti tuđim bogovima danju i noću: jer neću vam se više smilovati!'”"},{"v":14,"t":"“Zato, evo, dolaze dani - riječ je Jahvina - kad se više neće govoriti: 'Živoga mi Jahve koji sinove Izraelove izvede iz Egipta',"},{"v":15,"t":"nego: 'Živoga mi Jahve koji sinove Izraelove izvede iz zemlje sjeverne i iz svih zemalja kamo ih bijaše prognao.' Vratit ću ih u zemlju njihovu koju dadoh ocima njihovim."},{"v":16,"t":"Evo, poslat ću mnoga ribara - riječ je Jahvina - koji će ih uloviti. A zatim ću dovesti mnoge lovce koji će ih goniti sa svih gora, i sa svih brežuljaka, i iz svih pećinskih rasjeklina."},{"v":17,"t":"Jer moje oči prate sve njihove putove: neće mi izmaći, niti se bezakonje njihovo može sakriti od očiju mojih."},{"v":18,"t":"Dvostruko ću naplatiti njihovo bezakonje i grijehe njihove, jer su truplima svojih grozota oskvrnuli moju zemlju i moju baštinu ispunili gnusobama.”"},{"v":19,"t":"Jahve, snago moja i moja utvrdo, utočište moje u danima nevolje! K tebi će doći narodi s krajeva zemlje. I govorit će: Samu nam laž oci namriješe, Ništavost i Nemoć."},{"v":20,"t":"TÓa stvara li čovjek sam sebi bogove, to nikako nisu bogovi."},{"v":21,"t":"Učinit ću, evo, da osjete, da ovaj put zaista oćute moju ruku i snagu moju, i znat će da mi je ime Jahve."}]},"17":{"hr":[{"v":1,"t":"Judin grijeh upisan je željeznom pisaljkom, urezan dijamantnim vrškom u pločicu njihova srca i u rogove njihovih žrtvenika,"},{"v":2,"t":"kao spomen sinovima njihovim na žrtvenike njihove i ašere njihove oko zelenog drveća na visokim brežuljcima,"},{"v":3,"t":"na brdima i usred polja. Tvoje bogatstvo i sve blago tvoje pljački ću predati. Tako ćeš platiti za grijeh svoj po svoj zemlji."},{"v":4,"t":"Morat ćeš pustiti baštinu koju sam tebi poklonio. Učinit ću te robljem neprijatelja u zemlji koju ne poznaješ. Jer gnjev moj planu ognjem koji će vječno gorjeti."},{"v":5,"t":"Ovako govori Jahve: “Proklet čovjek koji se uzdaje u čovjeka, i slabo tijelo smatra svojom mišicom, i čije se srce od Jahve odvraća."},{"v":6,"t":"Jer on je kao drač u pustinji: ne osjeća kad je sreća na domaku, tavori dane u usahloj pustinji, u zemlji slanoj, nenastanjenoj."},{"v":7,"t":"Blagoslovljen čovjek koji se uzdaje u Jahvu i kome je Jahve uzdanje."},{"v":8,"t":"Nalik je na stablo zasađeno uz vodu što korijenje pušta k potoku: ne mora se ničeg bojati kad dođe žega, na njemu uvijek zelenilo ostaje. U sušnoj godini brigu ne brine, ne prestaje donositi plod."},{"v":9,"t":"Podmuklije od svega je srce. Jedva popravljivo, tko da ga pronikne?"},{"v":10,"t":"Ja, Jahve, istražujem srca i ispitujem bubrege, da bih dao svakom po njegovu vladanju, prema plodu ruku njegovih."},{"v":11,"t":"Prepelica što leži na jajima a ne leže jest onaj što nepravdom stječe bogatstvo: usred dana svojih ostavit' ga mora i na kraju ostaje lÓuda."},{"v":12,"t":"Slavan prijestol dignut od davnina, to je naše sveto mjesto."},{"v":13,"t":"O Jahve, nado Izraela, svi koji te ostave postidjet će se, koji se odmetnu od tebe bit će u prah upisani, jer ostaviše Izvor žive vode."},{"v":14,"t":"Iscijeli me, Jahve, i bit ću zdrav, spasi me, i bit ću spašen, jer ti si pjesma moja."},{"v":15,"t":"Evo ih što mi govore: Gdje je riječ Jahvina? Neka se ispuni!"},{"v":16,"t":"Ta ja se nisam vrzao oko tebe za njihovu nesreću niti sam želio kobni Dan! - ti to znaš, sve što je izlazilo iz usta mojih pred tobom je."},{"v":17,"t":"Ne budi mi na užas, ti, utočište moje, u Dan nesretni."},{"v":18,"t":"Progonitelji moji nek' se postide, ne ja, njih smeti, ne mene. Na njih dovedi Dan nesretni, zatri ih dvogubim zatorom!"},{"v":19,"t":"Ovako mi reče Jahve: “Idi i stani na vrata Sinova naroda na koja ulaze i izlaze kraljevi judejski i na sva vrata jeruzalemska."},{"v":20,"t":"Reci im: Čujte riječ Jahvinu, vi, kraljevi judejski i svi Judejci i Jeruzalemci koji prolazite kroz ova vrata."},{"v":21,"t":"Ovako govori Jahve: 'Čuvajte se ako vam je život mio i ne nosite tereta u dan subotnji, i ne unosite ga na vrata jeruzalemska."},{"v":22,"t":"I ne nosite bremena iz kuće u dan subotnji, i nikakva posla ne radite, nego svetkujte dan subotnji, kao što sam zapovjedio vašim ocima."},{"v":23,"t":"Oni me ne poslušaše i ne prikloniše uha svojega, nego tvrdovrato ne poslušaše i ne prihvatiše nauka."},{"v":24,"t":"A vi, ako me poslušate - riječ je Jahvina - i ako ne budete nosili bremena na vrata ovoga grada, nego budete svetkovali dan subotnji, ne radeći nikakva posla,"},{"v":25,"t":"tada će na vrata ovoga grada ulaziti kraljevi koji sjede na prijestolju Davidovu, koji se voze kolima i jašu na konjima, oni i njihovi časnici, Judejci i Jeruzalemci, i ovaj će grad ostati dovijeka."},{"v":26,"t":"I dolazit će iz gradova judejskih, iz okolice Jeruzalema, iz zemlje Benjaminove i iz Šefele, iz Gorja i iz Negeba, da prinesu paljenice, klanice, prinosnice i kad i da prinesu žrtvu zahvalnicu u Domu Jahvinu."},{"v":27,"t":"Ali ako me ne poslušate te ne budete svetkovali dan subotnji, i ako budete nosili bremena ulazeći na vrata jeruzalemska u dan subotnji, tada ću potpaliti oganj na vratima njegovim: i plamen će proždrijeti dvore jeruzalemske, i neće se ugasiti.'”"}]},"18":{"hr":[{"v":1,"t":"Ovo je riječ koju Jahve uputi Jeremiji:"},{"v":2,"t":"“Ustani i siđi u kuću lončarovu - ondje ću ti objaviti svoje riječi.”"},{"v":3,"t":"Siđoh, dakle, u kuću lončarovu, upravo je radio na lončarskom kolu."},{"v":4,"t":"I kako bi se koji sud što bi ga načinio od ilovače u ruci lončarovoj pokvario, on bi opet od nje pravio drugi - već kako se lončaru svidjelo da napravi."},{"v":5,"t":"I dođe mi riječ Jahvina:"},{"v":6,"t":"“Ne mogu li i ja s vama činiti kao ovaj lončar, dome Izraelov? - riječ je Jahvina. Evo, kao ilovača u ruci lončarovoj, i vi ste u mojoj ruci, dome Izraelov."},{"v":7,"t":"Objavim li jednom kojem narodu ili kojem kraljevstvu da ću ga iskorijeniti, uništiti i razoriti,"},{"v":8,"t":"i taj se narod, protiv kojeg sam govorio, obrati od opačina i zloća, tada ću se ja pokajati za zlo koje mu bijah namijenio."},{"v":9,"t":"Objavim li kojem narodu, ili kojem kraljevstvu, da ću ga izgraditi i posaditi,"},{"v":10,"t":"a on stane činiti što je zlo u mojim očima, ne slušajući glasa mojega, pokajat ću se za dobro koje sam im obećao."},{"v":11,"t":"Zato sada reci Judejcima i Jeruzalemcima: 'Ovako govori Jahve: Evo, spremam vam zlo i snujem protiv vas osnove. Vratite se, dakle, svaki sa svoga zlog puta i popravite svoje putove i svoja djela.'"},{"v":12,"t":"Ali oni vele: 'Uzalud! Mi ćemo radije provoditi svoje osnove i činiti svaki po okorjelosti zlog srca svojega.'”"},{"v":13,"t":"Ovako govori Jahve: “Propitajte se po narodima: je li itko takvo što čuo? Toliku grozotu učini djevica Izraelova."},{"v":14,"t":"Nestaje li s gorske vrleti snijeg libanonski? Mogu li presušiti vode daleke što studene teku?"},{"v":15,"t":"A narod moj mene zaboravi! Kad prinose ništavnosti, posrnuše na putovima svojim, na stazama drevnim, i hode stazama i putem neprohodnim."},{"v":16,"t":"I tako su zemlju u pustoš obratili, na vječnu porugu, da se nad njom zgraža svaki prolaznik glavom mašući."},{"v":17,"t":"Razvitlat ću ih pred neprijateljem, kao istočnjak; leđa, a ne lice, ja ću im pokazati u dan njine propasti.”"},{"v":18,"t":"I rekoše: “Hajdemo da se urotimo protiv Jeremije, jer svećeniku ne može nestati Zakona, ni mudrome savjeta, ni proroku besjede. Hajde, udarimo ga njegovim jezikom i pazimo budno na svaku riječ njegovu.”"},{"v":19,"t":"Poslušaj me, o Jahve, i čuj što govore moji protivnici."},{"v":20,"t":"TÓa zar se dobro uzvraća zlim? A oni mi jamu kopaju! Sjeti se kako stajah pred licem tvojim da u tebe milost tražim za njih, da odvratim od njih jarost tvoju."},{"v":21,"t":"Zato im djecu izruči gladi, maču ih predaj! Neka im žene ostanu jalove i udovice, neka im kuga pobije muževe, a mladići neka od mača u boju poginu."},{"v":22,"t":"Neka se prolomi vapaj iz kuća njihovih kad iznenada na njih dovedeš čete pljačkaša. Jer oni iskopaše jamu da me uhvate, nogama mojim u potaji zamke namjestiše."},{"v":23,"t":"Ti, o Jahve, znadeš sav njihov naum ubilački protiv mene. Ne oprosti im bezakonja njihova, ne izbriši im grijeha pred sobom. Neka padnu pred licem tvojim, obračunaj s njima u dan gnjeva svoga!"}]},"19":{"hr":[{"v":1,"t":"Ovako mi reče Jahve: “Idi i kupi vrč glineni. Povedi sa sobom nekoliko starješina narodnih i svećeničkih."},{"v":2,"t":"Pođi u Dolinu Ben Hinom, na ulazu Vrata lončarskih. Ondje proglasi riječi koje ću ti kazati."},{"v":3,"t":"Reci im: Čujte riječ Jahvinu, kraljevi judejski i stanovnici jeruzalemski. Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Evo dovodim nesreću na ovo mjesto te će svima koji to čuju u ušima zazujati."},{"v":4,"t":"Zato što su me ostavili i otuđili ovo mjesto prinoseći kad tuđim bogovima kojih ne poznavahu oci njihovi ni kraljevi judejski; i zato što su mjesto ovo natopili krvlju nevinih;"},{"v":5,"t":"i zato što pogradiše uzvišice Baalove da mu spaljuju sinove kao žrtve, a to im ja nikada ne naredih niti zapovjedih, niti mi je takvo što na um palo."},{"v":6,"t":"Stoga, evo, dolaze dani - riječ je Jahvina - kad se ovo mjesto neće više zvati Tofet ni Dolina Ben Hinom nego Dolina klanja."},{"v":7,"t":"Izjalovit ću na ovom mjestu naum Judeje i Jeruzalema i učiniti da svi poginu od neprijateljskog mača, od ruku onih što im rade o glavi. A trupla ću njihova dati za hranu pticama nebeskim i zvijerima poljskim."},{"v":8,"t":"A grad ću ovaj učiniti ruglom i užasom: svaki koji prođe mimo nj zgrozit će se i zviždati zbog svih nesreća njegovih."},{"v":9,"t":"I dat ću im da jedu meso sinova i kćeri svojih. Da, svaki će jesti meso bližnjega svoga zbog preteške nevolje kojom će ih pritisnuti njihovi neprijatelji što im rade o glavi.'"},{"v":10,"t":"Razbij vrč pred očima svojih pratilaca"},{"v":11,"t":"i reci im: Ovako govori Jahve nad Vojskama: 'Tako ću razbiti ovaj narod i ovaj grad, kao što se razbija sud lončarski, te se više ne da popraviti. U Tofetu će se ukapati, jer inače neće biti mjesta za ukapanje."},{"v":12,"t":"Tako ću postupiti s ovim mjestom - riječ je Jahvina - i sa stanovnicima njegovim. I učinit ću grad ovaj sličnim Tofetu."},{"v":13,"t":"I sve kuće jeruzalemske i kuće kraljeva judejskih bit će onečišćene kao mjesto Tofet: sve kuće kojima se na krovovima kad prinosi svoj vojsci nebeskoj i lijevaju ljevanice tuđim bogovima.'”"},{"v":14,"t":"Kad se Jeremija vratio iz Tofeta, kamo ga Jahve bijaše poslao da prorokuje, stade u predvorju Doma Jahvina te uze govoriti svemu narodu:"},{"v":15,"t":"“Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Evo, dovest ću na ovaj grad i na sve njegove gradiće sve zlo kojim sam im prijetio, jer ukrutiše vratove svoje ne slušajući riječi mojih.'”"}]},"20":{"hr":[{"v":1,"t":"A svećenik Pašhur, sin Imerov, vrhovni nadzornik Doma Jahvina, ču kako Jeremija prorokuje te riječi."},{"v":2,"t":"I Pašhur dade Jeremiju batinati i baci ga u klade što se nalaze kod gornjih vrata Benjaminovih, a u Domu su Jahvinu."},{"v":3,"t":"A kad sutradan Pašhur pusti Jeremiju iz klada, reče mu Jeremija: “Jahve te više ne zove Pašhur već 'Užas odasvud'."},{"v":4,"t":"Jer ovako govori Jahve: 'Evo, predajem te užasu, tebe i sve prijatelje tvoje, i poginut će od mača neprijatelja svojih, svojim ćeš očima vidjeti. I svu Judeju dat ću u ruke kralju babilonskom. On će ih odvesti u izgnanstvo u Babilon i mačem pobiti."},{"v":5,"t":"I sve bogatstvo ovoga grada, sav njegov trudom stečeni imetak i sve dragocjenosti te sve blago kraljeva judejskih predat ću u ruke neprijateljima. Oni će sve opljačkati, ugrabiti i u Babilon odnijeti.'"},{"v":6,"t":"A ti ćeš se, Pašhure, sa svim svojim ukućanima seliti u Babilon. Da, u Babilon ćeš doći i ondje umrijeti i biti pokopan, ti i svi tvoji prijatelji kojima si laži prorokovao.”"},{"v":7,"t":"Ti me zavede, o Jahve, i dadoh se zavesti, nadjačao si me i svladao me. A sada sam svima na podsmijeh iz dana u dan, svatko me ismijava."},{"v":8,"t":"Jer kad god progovorim, moram vikati, naviještati moram: “Nasilje! Propast!” Doista, riječ mi Jahvina postade na ruglo i podsmijeh povazdan."},{"v":9,"t":"I rekoh u sebi: neću više na nj misliti niti ću govoriti u njegovo ime. Al' tad mi u srcu bi kao rasplamtjeli oganj, zapretan u kostima mojim: uzalud se trudih da izdržim, ne mogoh više."},{"v":10,"t":"Čuh klevete mnogih: “Užas odasvud! Prijavite! Mi ćemo ga prijaviti.” Svi koji mi bijahu prijatelji čekahu moj pad. “Možda ga zavedemo, pa ćemo njim ovladati i njemu se osvetiti!”"},{"v":11,"t":"Sa mnom je Jahve kao snažan junak! Zato će progonitelji moji posrnuti i neće nadvladati, postidjet će se veoma zbog poraza, zbog nezaboravne vječne sramote."},{"v":12,"t":"O Jahve nad Vojskama, koji proničeš pravednika i vidiš mu bubrege i srce, daj da vidim kako im se osvećuješ, jer tebi povjerih parnicu svoju."},{"v":13,"t":"Pjevajte Jahvi, hvalite Jahvu, jer on izbavi dušu sirote iz ruku zlikovaca."},{"v":14,"t":"Proklet bio dan kad se rodih, dan kad me rodi majka moja ne bio blagoslovljen!"},{"v":15,"t":"Proklet bio čovjek koji ocu mom dojavi: “Rodio ti se sin, muškić!” i time mi oca obradova."},{"v":16,"t":"Tom čovjeku bilo kao gradovima što ih Jahve nemilice razvali; već u cik zore čuo zapomaganje i poklike bojne u podne,"},{"v":17,"t":"jer me ne pogubi u majčinoj utrobi da bi majka bila moj grob, da bi joj utroba dovijeka ostala trudna!"},{"v":18,"t":"O, zašto izađoh iz majčina krila? Da vidim jad i nevolju i u sramoti da dokončam dane!"}]},"21":{"hr":[{"v":1,"t":"Riječ koju Jahve uputi Jeremiji kad kralj Sidkija posla k njemu Pašhura, sina Malkijina, i svećenika Sefaniju, sina Maasejina, s porukom:"},{"v":2,"t":"“Hajde, upitaj Jahvu za nas, jer je Nabukodonozor, kralj babilonski, zavojštio na nas; možda će Jahve opet učiniti s nama čudo, pa će se neprijatelj povući pred nama.”"},{"v":3,"t":"Jeremija im reče: “Ovako recite Sidkiji:"},{"v":4,"t":"Ovako govori Jahve, Bog Izraelov: 'Povući ću oružje koje je u vašim rukama, kojim se borite protiv kralja babilonskoga i Kaldejaca što vas napadaju izvan zidina, i skupiti ga usred ovoga grada."},{"v":5,"t":"I sam ću se boriti protiv vas ispruženom rukom i snažnom mišicom, u srdžbi i gnjevu i velikoj jarosti."},{"v":6,"t":"I strašnom kugom udarit ću stanovnike ovoga grada, ljude i životinje, i pomrijet će."},{"v":7,"t":"Poslije toga ću - riječ je Jahvina - Sidkiju, kralja judejskoga, i njegove sluge i narod, i sve one koji preostadoše u tom gradu nakon pošasti, mača i gladi, predati u ruke Nabukodonozora, kralja babilonskoga, u ruke njihovih neprijatelja i u ruke onih koji im rade o glavi; on će ih sasjeći oštricom mača bez samilosti, bez milosrđa i bez smilovanja.'"},{"v":8,"t":"A ovom narodu reci: 'Ovako govori Jahve: Evo stavljam pred vas put života i put smrti."},{"v":9,"t":"Tko ostane u ovom gradu, poginut će od mača, gladi i kuge. A tko izađe, te se preda Kaldejcima koji vas opsjedaju, spasit će život - život će mu ostati kao plijen."},{"v":10,"t":"Jer, okrenuh lice svoje ovomu gradu na zlo, a ne na dobro - riječ je Jahvina - i bit će izručen u ruke kralja babilonskoga, i on će ga vatrom spaliti.'”"},{"v":11,"t":"Kraljevskom domu Judeje. Čujte riječ Jahvinu,"},{"v":12,"t":"dome Davidov! Ovako govori Jahve: “Svako jutro sudite pravedno, izbavite potlačene iz ruku tlačitelja, ili će moj gnjev planut' poput vatre, raspalit' se neugasivo zbog vaših opačina."},{"v":13,"t":"Evo me protiv tebe koji stanuješ na Pećini dolinskoj - riječ je Jahvina - protiv vas koji kažete: 'Tko može na nas navaliti, tko u naše nastambe prodrijeti?'"},{"v":14,"t":"Al' ja ću vam platiti prema plodu djela vaših - riječ je Jahvina. - Oganj ću podmetnuti šumi njegovoj i proždrijet će sve oko nje!”"}]},"22":{"hr":[{"v":1,"t":"Ovako govori Jahve: “Siđi u palaču kralja judejskoga i objavi ondje ovu riječ."},{"v":2,"t":"Reci: Slušaj riječ Jahvinu, kralju judejski, koji sjediš na prijestolju Davidovu, ti i tvoje sluge i tvoj narod koji ulaze na ova vrata."},{"v":3,"t":"Ovako govori Jahve: 'Činite pravo i pravicu, izbavite potlačene iz ruku tlačitelja! Ne činite krivo strancu, siroti, udovici, ne tlačite ih i ne prolijevajte krvi nedužne na ovome mjestu."},{"v":4,"t":"Jer budete li se istinski vladali po riječi ovoj, na vrata ovog dvora ulazit će kraljevi što sjede na prijestolju Davidovu, voze se na kolima i jašu na konjima - oni, njihove sluge i njihov narod."},{"v":5,"t":"Ako pak ne poslušate ovih riječi, zaklinjem se sobom - riječ je Jahvina - da ću taj dvor pretvoriti u ruševinu!'”"},{"v":6,"t":"Jer ovako govori Jahve o dvoru kralja judejskoga: “Ti si za me Gilead, vrh libanonski. Ali, uistinu, pretvorit ću te u pustinju, u grad nenastanjen."},{"v":7,"t":"Spremit ću protiv tebe zatirače, svakoga s oružjem njegovim, nek' posijeku izabrane ti cedrove i u vatru ih pobacaju.”"},{"v":8,"t":"Mnoštvo će naroda prolaziti mimo taj grad i pitat će jedan drugoga: “Zašto je Jahve tako postupio s ovim velikim gradom?”"},{"v":9,"t":"Odgovorit će im: “Jer su ostavili Savez Jahve, Boga svoga, klanjali se drugim bogovima i služili im.”"},{"v":10,"t":"Ne oplakujte mrtvoga, ne jadikujte za njim. Radije plačite za onim koji odlazi, jer se nikad više neće vratiti ni rodne grude vidjeti."},{"v":11,"t":"Jer ovako govori Jahve o Šalumu, sinu Jošijinu, kralju judejskomu, koji kraljevaše mjesto oca svoga i morade otići iz ovoga mjesta: “Nikad se više neće vratiti,"},{"v":12,"t":"nego će umrijeti u mjestu kamo ga izagnaše, a ovu zemlju nikad više neće vidjeti.”"},{"v":13,"t":"Jao onom koji kuću gradi nepravedno i gornje odaje diže bez prava; koji bližnjega tjera na tlaku i plaću mu ne isplaćuje;"},{"v":14,"t":"koji kaže: “Sagradit ću sebi kuću prostranu i prozračne gornje odaje!” koji probija prozore, oblaže ih cedrovinom crveno obojenom."},{"v":15,"t":"Jesi li zato kralj što se cedrom razmećeš? Nije li ti i otac jeo i pio, ali je činio pravo i pravicu i zato mu bješe dobro."},{"v":16,"t":"Branio je pravo siromaha i jadnika, i zato mu bješe dobro. Zar ne znači to mene poznavati? - riječ je Jahvina."},{"v":17,"t":"Ali tvoje oči i srce idu samo za dobitkom, da krv nevinu prolijevaš, da nasilje činiš i krivdu."},{"v":18,"t":"Zato ovako govori Jahve o Jojakimu, sinu Jošijinu, kralju judejskom: “Za njim neće naricati: 'Jao, brate moj! Jao, sestro moja!' Za njim neće naricati: 'Jao, gospodaru! Jao, veličanstvo!'"},{"v":19,"t":"Pokopat će ga k'o magarca, izvući ga i baciti izvan vrata Jeruzalema.”"},{"v":20,"t":"“Popni se na Libanon i viči, po Bašanu nek' se ori glas, s Abarima buči, jer svi su tvoji prijatelji slomljeni!"},{"v":21,"t":"Lijepo sam te svjetovao u danima mirnim, al' ti mi reče: 'Neću slušati!' Tako se vladaš od mladosti: ne slušaš glasa mojega."},{"v":22,"t":"Sve će tvoje pastire vjetar popasti, a ljubavnici će tvoji u izgnanstvo. Tada ćeš se stidjet' i sramiti zbog sve pakosti svoje."},{"v":23,"t":"Ti što prebivaš na Libanonu, ti što se gnijezdiš po cedrovima, kako li ćeš stenjati kad bolovi te spopadnu, trudovi porodilje."},{"v":24,"t":"Života mi moga - riječ je Jahvina - kad bi Konija, sin Jojakimov, kralj judejski, bio pečatnjak na mojoj desnici, ja bih ga strgao s prsta."},{"v":25,"t":"Dat ću te u ruke onima koji ti rade o glavi, u ruke onima pred kojima dršćeš, u ruke Nabukodonozora, kralja babilonskog, i u ruke Kaldejaca."},{"v":26,"t":"I bacit ću tebe i majku koja te rodila u drugu zemlju gdje se niste rodili; tamo ćete umrijeti."},{"v":27,"t":"Ali u zemlju u koju čeznu da se vrate neće se vratiti!”"},{"v":28,"t":"TÓa zar je taj čovjek Konija sud prezren, razbijen? Il' posuda što nikom se ne sviđa? Zašto bjehu protjerani on i potomstvo, prognani u zemlju koja im je posve neznana?"},{"v":29,"t":"Zemljo, zemljo, zemljo, poslušaj riječ Jahvinu."},{"v":30,"t":"Ovako govori Jahve: “Upišite za ovoga čovjeka: 'Bez djece. Život mu se nije posrećio. Nitko od potomstva njegova neće sjesti na prijesto Davidov ni vladati Judejom.'”"}]},"23":{"hr":[{"v":1,"t":"“Jao pastirima koji upropašćuju i raspršuju ovce paše moje” - riječ je Jahvina."},{"v":2,"t":"Stoga ovako govori Jahve, Bog Izraelov, protiv pastira koji pasu narod moj: “Vi ste raspršili ovce moje, rastjerali ih, niste se brinuli za njih. Zato ću se ja sada pobrinuti za vas zbog zlodjela vaših - riječ je Jahvina."},{"v":3,"t":"I sam ću skupiti ostatak svojih ovaca iz svih zemalja kamo sam ih raspršio i vratiti ih na ispaše njihove: bit će plodne i množit će se."},{"v":4,"t":"I podići ću im pastire da ih pasu te se ničega više neće bojati ni plašiti, niti će se gubiti” - riječ je Jahvina."},{"v":5,"t":"“Evo dolaze dani - riječ je Jahvina - podići ću Davidu izdanak pravedni. On će vladati kao kralj i biti mudar i činit će pravo i pravicu u zemlji."},{"v":6,"t":"U njegove će dane Judeja biti spašena i Izrael će živjeti spokojno. I evo imena kojim će ga nazivati: 'Jahve, Pravda naša.'"},{"v":7,"t":"Zato, evo, dolaze dani - riječ je Jahvina - kad se više neće govoriti: 'Živoga mi Jahve koji sinove Izraelove izvede iz zemlje egipatske',"},{"v":8,"t":"nego: 'Živoga mi Jahve koji potomstvo doma Izraelova izvede i dovede iz zemlje sjeverne i iz svih zemalja kamo ih bijaše prognao, tako da obitavaju u zemlji svojoj.'”"},{"v":9,"t":"Prorocima. Srce je u meni skrhano, dršću mi kosti, sličan sam pijancu, čovjeku kojim vino ovlada, pred licem Jahvinim i njegovim svetim riječima:"},{"v":10,"t":"“Jer zemlja je puna preljubnika; zbog tih se ljudi zemlja u crno zavila, a ispaše u pustinji sagorješe. Njihova je trka zloba, a moć im je nepravda."},{"v":11,"t":"Da, i prorok i svećenik zlikovci su, čak i u Domu svome nađoh im pakost” - riječ je Jahvina."},{"v":12,"t":"Stog' će im se puti prometnuti u tlo klizavo: u mraku će posrtati i padati. Jer ja ću na njih svaliti nesreću u godine kazne njihove” - riječ je Jahvina."},{"v":13,"t":"“I u proroka Samarije vidjeh mnoge ludosti: prorokuju u Baalovo ime i zavode narod moj izraelski."},{"v":14,"t":"Ali u proroka jeruzalemskih vidjeh strahote: preljub, prijevarne putove, jačaju ruke zločincima, te se nitko od zločina svojih ne obraća. Svi su mi oni kao Sodoma, a žitelji kao Gomora!”"},{"v":15,"t":"I zato Jahve nad Vojskama ovako govori o prorocima: “Evo, nahranit ću ih pelinom i napojiti vodom zatrovanom, jer od proroka jeruzalemskih potječe pokvara u svoj zemlji.”"},{"v":16,"t":"Ovako govori Jahve nad Vojskama: “Ne slušajte riječi proroka: oni vas obmanjuju, objavljuju viđenja srca svoga, a ne što dolazi iz usta Jahvinih;"},{"v":17,"t":"govore onima što preziru riječ Jahvinu: 'Bit će s vama mir!' a onima što slijede glas svog srca okorjelog: 'Nikakvo vas zlo neće snaći!'”"},{"v":18,"t":"TÓa tko bijaše na vijećanju Jahvinu, tko je vidio, tko slušao riječ njegovu? Tko ju je shvatio te je može objaviti?"},{"v":19,"t":"Gle, nevrijeme Jahvino: jarost provaljuje, razmahuje se vihor silan i svaljuje na glave bezbožničke."},{"v":20,"t":"Jahvin se gnjev neće stišati, dok on ne izvrši i ne ispuni naume srca svojega. U dane posljednje jasno ćete to razumjeti."},{"v":21,"t":"“Ne poslah ti proroka, a ipak trče! Ne govorih im, a ipak prorokuju!"},{"v":22,"t":"Jest, da bijahu na mom vijećanju, moje bi riječi narodu mom obznanili, i kušali ih svrnuti sa zla puta njihova i od zlodjela njihovih!"},{"v":23,"t":"TÓa, zar sam ja Bog samo iz blizine - riječ je Jahvina - zar iz daljine nisam više Bog?"},{"v":24,"t":"Može li se tko skriti u skrovištima da ga ja ne vidim? - riječ je Jahvina. Ne ispunjam li ja nebo i zemlju? - riječ je Jahvina."},{"v":25,"t":"Čuo sam što govore proroci koji prorokuju laži u ime moje i tvrde: 'Usnio sam! Usnio sam!'"},{"v":26,"t":"Dokle će među prorocima biti onih koji prorokuju laž i objavljuju prijevaru srca svojega?"},{"v":27,"t":"Misle da će svojim snima što ih jedan drugom pripovijedaju postići da narod moj zaboravi ime moje, kao što već oci njihovi zaboraviše ime moje uz Baala!"},{"v":28,"t":"Prorok koji je usnio san neka samo pripovijeda svoj san, a u koga je riječ moja, neka po istini objavljuje riječ moju!” “Što je zajedničko slami i žitu? - riječ je Jahvina."},{"v":29,"t":"Nije li riječ moja poput vatre - riječ je Jahvina - i nije li slična malju što razbija pećinu?"},{"v":30,"t":"Evo me stoga protiv proroka - riječ je Jahvina - koji jedan drugome kradu moje riječi."},{"v":31,"t":"Evo me protiv proroka - riječ je Jahvina - koji mlate jezikom i proroštva kuju."},{"v":32,"t":"Evo me protiv proroka - riječ je Jahvina - koji prorokuju izmišljene snove i pripovijedajući ih zavode narod moj izmišljotinama svojim i lažima. A ja ih nisam poslao, niti sam im što zapovjedio, niti su narodu ovome od kakve koristi - riječ je Jahvina."},{"v":33,"t":"A ako te ovaj narod, ili prorok, ili svećenik, zapita: 'Što je breme Jahvino?' odgovori im: 'Vi ste breme Jahvino i ja vas odbacujem' - riječ je Jahvina."},{"v":34,"t":"A reče li koji prorok ili svećenik, ili tko iz naroda: 'Breme Jahvino', kaznit ću toga čovjeka i dom njegov."},{"v":35,"t":"Ovako morate govoriti svaki svome bližnjemu i svaki svome bratu: 'Što je Jahve odgovorio?' ili 'Što je Jahve rekao?'"},{"v":36,"t":"Ali 'Breme Jahvino' da više niste spomenuli, jer je breme svakome riječ njegova.” Jer vi iskrivljujete riječi Boga živoga, Jahve nad Vojskama, našega Boga!"},{"v":37,"t":"Ovako reci proroku: “Što ti je Jahve odgovorio?” ili “Što je Jahve rekao?”"},{"v":38,"t":"Ali ako kažete “Breme Jahvino”, ovako govori Jahve: “Zato što se služite riječju 'Breme Jahvino', premda sam vam poručio da je ne izgovarate,"},{"v":39,"t":"ja ću visoko podići i odbaciti od lica svojega vas i vaš grad što ga dadoh vama i ocima vašim!"},{"v":40,"t":"I svalit ću na vas vječnu sramotu i vječnu porugu koja se neće zaboraviti.”"}]},"24":{"hr":[{"v":1,"t":"Jahve mi pokaza, i gle: dvije kotarice smokava stajahu pred Domom Jahvinim, pošto Nabukodonozor, kralj babilonski, odvede iz Jeruzalema i izagna u Babilon Jekoniju, sina Jojakimova, kralja judejskoga, zajedno s knezovima judejskim, kovačima i bravarima."},{"v":2,"t":"U jednoj kotarici bijahu izvrsne smokve, kakve već jesu rane smokve; a u drugoj bijahu pokvarene smokve, tako rđave da se ne mogahu jesti."},{"v":3,"t":"I Jahve me upita: “Jeremija, što vidiš?” A ja odgovorih: “Smokve! Dobre su vrlo dobre, a loše su vrlo loše - tako loše da nisu za jelo.”"},{"v":4,"t":"I dođe mi riječ Jahvina:"},{"v":5,"t":"Ovako govori Jahve, Bog Izraelov: “Kao na ove dobre smokve, tako ću milostivo pogledati na sužnje judejske koje sam s ovoga mjesta prognao u zemlju kaldejsku."},{"v":6,"t":"I milostivo ću svrnuti oči na njih i vratiti ih u ovu zemlju. Ponovo ću ih podići i neću ih više uništiti; opet ću ih posaditi i neću ih više iščupati."},{"v":7,"t":"I dat ću im srce da me poznaju da sam ja Jahve, da budu narod moj, a ja Bog njihov, jer će se oni svim srcem svojim opet k meni obratiti."},{"v":8,"t":"Ali kao s lošim smokvama koje su tako loše da nisu za jelo - da, riječ je Jahvina - tako ću postupiti i sa Sidkijom, kraljem judejskim, s njegovim knezovima i sa svim Jeruzalemcima što preostadoše u ovoj zemlji i s onima što se u Egiptu nastaniše."},{"v":9,"t":"Učinit ću da budu na užas svim kraljevstvima zemaljskim, na sramotu i porugu, na ruglo i kletvu posvuda kamo ih protjeram."},{"v":10,"t":"I poslat ću na njih mač, glad i kugu dok se ne istrijebe sa zemlje koju dadoh njima i ocima njihovim.”"}]},"25":{"hr":[{"v":1,"t":"Riječ upućena Jeremiji o svem narodu judejskom, četvrte godine Jojakima, sina kralja judejskog - to je prve godine Nabukodonozora, kralja babilonskog."},{"v":2,"t":"Prorok"},{"v":3,"t":"Od trinaeste godine Jošije, sina Amonova, kralja judejskoga, sve do dana današnjeg, ove dvadeset i tri godine, dolazila mi je riječ Jahvina i ja sam vam jednako govorio, ali me niste slušali."},{"v":4,"t":"I Jahve je svejednako slao k vama sve sluge svoje, proroke, ali vi niste slušali i niste prignuli uši svoje da čujete."},{"v":5,"t":"I govorahu vam: “Vratite se svaki sa zla puta svojega i od zlih djela svojih i ostanite u zemlji koju Jahve dade vama i ocima vašim za sva vremena;"},{"v":6,"t":"i ne idite za tuđim bogovima da im služite i da im se klanjate; i ne gnjevite me djelima ruku svojih, pa vam neću ništa nažao učiniti."},{"v":7,"t":"Ali me niste poslušali - riječ je Jahvina - nego me razgnjeviste djelima ruku svojih, na svoju nesreću!”"},{"v":8,"t":"Zato ovako govori Jahve nad Vojskama: “Jer niste poslušali mojih riječi,"},{"v":9,"t":"evo, ja ću poslati i podignuti sve narode sa sjevera - riječ je Jahvina - i slugu svoga Nabukodonozora, kralja babilonskoga, i dovest ću ih na ovu zemlju i na njene stanovnike i na sve okolne narode; izručit ću ih kletom uništenju i učinit ću ih užasom i ruglom, vječnim razvalinama."},{"v":10,"t":"I ugušit ću među njima svaki glas radosti i veselja, klicanje zaručnika i zaručnice i klopot žrvnja i svjetlost svjetiljke."},{"v":11,"t":"Sva će se zemlja pretvoriti u pustoš i pustinju i svi će narodi služiti kralju babilonskom sedamdeset godina."},{"v":12,"t":"Ali kad se navrši sedamdeset godina, kaznit ću kralja babilonskog i narod onaj - riječ je Jahvina - za bezakonje njihovo i zemlju kaldejsku i pretvorit ću ih u vječne razvaline."},{"v":13,"t":"Dovest ću na tu zemlju sve što sam protiv nje rekao - sve je to napisano u ovoj knjizi, što prorokova Jeremija za sve narode.”"},{"v":14,"t":"“I oni će služiti mnogim narodima i velikim kraljevima i platit ću im po njihovim činima i po djelima ruku njihovih.”"},{"v":15,"t":"Ovako mi reče Jahve, Bog Izraelov: “Uzmi ovaj pehar vina iz moje ruke i napoji njime sve narode kojima ću te poslati."},{"v":16,"t":"Neka piju dok ne zateturaju i dok se ne izbezume zbog mača što ću ga među njih poslati.”"},{"v":17,"t":"I uzeh pehar iz ruke Jahvine i napojih njime sve narode kojima me Jahve bijaše poslao:"},{"v":18,"t":"Jeruzalem i gradove judejske s njihovim kraljevima i knezovima, neka budu razvalina, pustoš, ruglo i prokletstvo, kao što su i danas;"},{"v":19,"t":"faraona, kralja egipatskoga, s njegovim slugama i knezovima i narodom njegovim"},{"v":20,"t":"i svu onu mješavinu naroda: sve kraljeve zemlje Usa, sve kraljeve zemlje filistejske, Aškelon, Gazu, Ekron i ono što ostade od Ašdoda;"},{"v":21,"t":"Edom, Moab i sinove Amonove;"},{"v":22,"t":"sve kraljeve Tira, sve kraljeve Sidona, kraljeve otoka onkraj mora;"},{"v":23,"t":"Dedan, Temu, Buz i sve one ostriženih zalizaka,"},{"v":24,"t":"sve kraljeve Arabije, sve kraljeve mješavine naroda koji obitavaju u pustinji;"},{"v":25,"t":"sve kraljeve Zimrija, sve kraljeve Elama i sve kraljeve Medije;"},{"v":26,"t":"sve kraljeve Sjevera, blize i daleke, jednog za drugim, i sva kraljevstva na licu zemlje. A kralj Šešak pit će poslije njih."},{"v":27,"t":"I reci im: “Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Pijte! Opijte se! Bljujte! Padnite da se više ne dignete od mača koji ću pustiti među vas.'"},{"v":28,"t":"Ako ne bi htjeli uzeti pehar iz tvoje ruke da piju, reci im: 'Ovako govori Jahve nad Vojskama: Morate piti!"},{"v":29,"t":"Jer, evo, ja sam počeo kažnjavati grad koji se zove mojim imenom. A vi zar da prođete bez kazne? Ne, nećete ostati nekažnjeni, jer ću sam dozvati mač da udari na sve stanovnike zemlje' - riječ je Jahve nad Vojskama."},{"v":30,"t":"Ti im, dakle, prorokuj sve riječi ove i reci im: 'Jahve reče sa visine, iz svetoga stana grmi glasom, riče iza glasa protiv pašnjaka svoga, podvikuje kao oni što grožđe gaze. Do svih stanovnika zemlje"},{"v":31,"t":"dopire bojni klik - do nakraj svijeta - jer Jahve se parbi s narodima, izlazi na sud sa svakim tijelom, bezbožnike će maču izručiti - riječ je Jahvina."},{"v":32,"t":"Ovako govori Jahve nad Vojskama: Evo, nesreća već zahvaća narod za narodom; nevrijeme strašno već se prolama s krajeva zemlje.'”"},{"v":33,"t":"U onaj dan bit će pobijenih Jahvinih s jednoga kraja svijeta do drugoga. Za njima nitko neće naricati, niti će ih tko pokupiti i sahraniti; ostat će kao gnoj po zemlji."},{"v":34,"t":"Kukajte, pastiri, i vičite, valjajte se po prašini, vodiči stada, jer vam se ispuniše dani za klanje, popadat ćete ko ovnovi izabrani."},{"v":35,"t":"Više nema utočišta pastirima, niti spasa vodičima stada."},{"v":36,"t":"Čuj, kako vapiju pastiri, kako kukaju vodiči stada, jer Jahve pustoši pašnjak njihov,"},{"v":37,"t":"mirna su pasišta poharana od jarosna gnjeva Jahvina."},{"v":38,"t":"Lav ostavlja guštaru jer će zemlja njihova opustjeti od mača pustošničkog, od jarosnog gnjeva Jahvina."}]},"26":{"hr":[{"v":1,"t":"U početku kraljevanja Jojakima, sina Jošijina, kralja Judina, dođe mi riječ Jahvina."},{"v":2,"t":"Ovako govori Jahve: “Stani u predvorju Doma Jahvina i svim gradovima judejskim koji dolaze da se poklone u Domu Jahvinu naviještaj sve riječi koje sam ti zapovjedio da im kažeš. I ne izostavi ni jedne jedine."},{"v":3,"t":"Možda će poslušati i vratiti se svaki sa zla puta svoga, pa ću se pokajati za zlo koje naumih učiniti zbog zlodjela njihovih."},{"v":4,"t":"Reci im: 'Ovako govori Jahve: Ako me ne poslušate da hodite po Zakonu što ga stavih pred vas,"},{"v":5,"t":"slušajući riječi slugu mojih proroka koje vam neumorno šaljem, premda ih do sada niste slušali,"},{"v":6,"t":"postupit ću s ovim Domom kao sa Šilom i učinit ću da ovaj grad bude prokletstvo za sve narode na zemlji.'”"},{"v":7,"t":"I svećenici i proroci i sav narod slušahu Jeremiju kako naviješta te riječi u Domu Jahvinu."},{"v":8,"t":"A kad Jeremija izreče sve ono što mu je Gospod zapovjedio da naviješta svemu narodu, zgrabiše ga svećenici i proroci govoreći: “Platit ćeš glavom!"},{"v":9,"t":"Zašto si u ime Jahvino prorokovao: 'Postupit ću s ovim Domom kao sa Šilom i ovaj će grad biti opustošen te nitko više u njemu neće stanovati?'” I sav se narod skupi na Jeremiju u Domu Jahvinu."},{"v":10,"t":"Čuvši to, starješine judejske dođoše iz kraljevskog dvora u Dom Jahvin i sjedoše pred Nova vrata Doma Jahvina."},{"v":11,"t":"Tada svećenici i proroci rekoše starješinama i svemu narodu: “Ovaj je čovjek zaslužio smrt jer je prorokovao protiv ovoga grada, kao što ste čuli na svoje uši.”"},{"v":12,"t":"Tada Jeremija reče starješinama i svemu narodu: “Jahve me posla da prorokujem protiv ovoga Doma i ovoga grada sve ono što ste čuli."},{"v":13,"t":"Popravite, dakle, putove svoje i djela svoja i slušajte glas Jahve, Boga svoga: i pokajat će se za zlo kojim vam se zaprijetio."},{"v":14,"t":"Ja sam, evo, u vašim rukama. Učinite sa mnom što vam se čini dobro i pravo."},{"v":15,"t":"Ali dobro znajte: ako me pogubite, krv nedužnu navalit ćete na sebe, na ovaj grad i na njegove stanovnike. Jer, zaista, Jahve me posla k vama da u vaše uši govorim sve ove riječi.”"},{"v":16,"t":"Tada rekoše starješine i sav narod svećenicima i prorocima: “Ovaj čovjek nipošto ne zaslužuje smrt, jer nam je govorio u ime Jahve, Boga našega.”"},{"v":17,"t":"Nato ustadoše i neki od najuglednijih u zemlji te rekoše svemu mnoštvu naroda što se ondje okupilo:"},{"v":18,"t":"“Mihej Morešećanin prorokovaše u dane Ezekije, kralja judejskog, i govoraše svemu narodu judejskom: 'Ovako govori Jahve nad Vojskama: Sion će biti polje preorano, Jeruzalem ruševina, a Goru Doma ovog šuma će prekriti.'"},{"v":19,"t":"Je li ga zato pogubio Ezekija, kralj judejski, i sva Judeja? Nisu li se pobojali Jahve i nastojali da Jahvu umilostive, te se Jahve pokaja za zlo kojim im se bijaše zaprijetio? A mi, zar da na duše svoje navalimo tako velik zločin?”"},{"v":20,"t":"Bijaše ondje još neki koji prorokovaše u ime Jahvino, Urija, sin Šemajin, rodom iz Kirjat Jearima. I on prorokovaše protiv ovoga grada i zemlje ove kao i Jeremija."},{"v":21,"t":"A kad je kralj Jojakim sa svim ratnicima i zapovjednicima čuo te riječi, tražio je da ga smakne. Čuvši to, Urija se prestraši i pobježe u Egipat."},{"v":22,"t":"Ali kralj Jojakim posla u Egipat Elnatana, sina Akborova, s nekoliko ljudi;"},{"v":23,"t":"dovedoše oni Uriju iz Egipta i odvedoše ga kralju Jojakimu, koji ga mačem pogubi, a truplo njegovo baci na groblje prostoga puka."},{"v":24,"t":"Ali Ahikam, sin Šafanov, zaštiti Jeremiju te ga ne predaše u ruke narodu da ga pogube."}]},"27":{"hr":[{"v":1,"t":"U početku kraljevanja Sidkije, sina Jošije, kralja judejskoga, uputi Jahve Jeremiji ovu riječ."},{"v":2,"t":"Ovako mi reče Jahve: “Načini sebi užad i jaram i stavi ga sebi na vrat."},{"v":3,"t":"Zatim poruči kralju edomskom, kralju moapskom, kralju amonskom, kralju tirskom i kralju sidonskom, po njihovim izaslanicima koji su došli u Jeruzalem kralju judejskom Sidkiji."},{"v":4,"t":"Naredi im da poruče svojim gospodarima: 'Ovako govori Jahve nad Vojskama, Bog Izraelov! Ovako poručite svojim gospodarima:"},{"v":5,"t":"Ja sam snagom svojom svesilnom i rukom ispruženom stvorio zemlju, ljude i životinje na zemlji. I ja to dajem kome hoću."},{"v":6,"t":"Sada, dakle, sve te zemlje dajem u ruke Nabukodonozoru, kralju babilonskom, sluzi svojemu; dajem mu i poljsko zvijerje da mu služi."},{"v":7,"t":"I svi će narodi služiti njemu i njegovu sinu, i sinu njegova sina, dok i njegovoj zemlji ne kucne čas te i njega ne upokore moćni narodi i veliki kraljevi."},{"v":8,"t":"Ako koji narod, ili kraljevstvo, ne htjedne služiti Nabukodonozora, kralja babilonskoga, ne hoteć' se upregnuti u jaram kralja babilonskog, taj ću narod kazniti mačem, glađu i kugom - riječ je Jahvina - dok ga sasvim ne zatrem rukom njegovom."},{"v":9,"t":"Ne slušajte, dakle, svojih proroka, gatalaca, sanjara, zvjezdara svojih i čarobnjaka koji vam govore: 'Ne, vi nećete služiti kralju babilonskom!'"},{"v":10,"t":"Jer vam oni laž prorokuju samo da vas udalje iz vaše zemlje, da vas otjeram pa da propadnete."},{"v":11,"t":"Ali narod koji se upregne u jaram kralja babilonskoga da mu služi ostavit ću na miru u zemlji njegovoj - riječ je Jahvina - da je obrađuje i u njoj živi.'”"},{"v":12,"t":"Sve sam to rekao Sidkiji, kralju judejskom, govoreći: “Upregnite se u jaram kralja babilonskoga i pokorite se njemu i narodu njegovu da ostanete živi."},{"v":13,"t":"Zašto da poginete, ti i narod tvoj, od mača, gladi i kuge, kao što se Jahve zaprijetio narodu koji se ne podvrgne kralju babilonskom?"},{"v":14,"t":"Ne slušajte, dakle, riječi onih proroka koji vam govore: 'Vi nećete služiti kralju babilonskom.' Oni vam laž prorokuju."},{"v":15,"t":"'Jer nisam ih ja poslao da vam prorokuju - riječ je Jahvina - nego vam oni laž prorokuju u moje ime, da vas otjeram iz vaše zemlje, pa da propadnete - vi i proroci koji vam prorokuju.'”"},{"v":16,"t":"I svećenicima i svemu ovom narodu rekao sam: “Ovako govori Jahve: 'Ne slušajte riječi svojih proroka koji vam ovako prorokuju: Evo, posuđe Doma Jahvina bit će uskoro vraćeno iz Babilona.' Oni vam laži prorokuju."},{"v":17,"t":"Ne slušajte ih! Pokorite se kralju babilonskom da ostanete živi! Zašto da ovaj grad postane ruševina?"},{"v":18,"t":"Ako su oni zaista proroci, te ako je u njima riječ Jahvina, neka mole Jahvu nad Vojskama da i posuđe što još ostade u Domu Jahvinu i u dvoru kraljeva judejskih i u Jeruzalemu ne dospije u Babilon!"},{"v":19,"t":"Jer ovako govori Jahve o stupovima, moru, podnožjima i o preostalom posuđu što još ostade u ovome gradu -"},{"v":20,"t":"što još Nabukodonozor, kralj babilonski, ne uze sa sobom onda kad odvede u izgnanstvo iz Jeruzalema u Babilon Jekoniju, sina Jojakimova, kralja judejskoga, i sve odličnike judejske i jeruzalemske."},{"v":21,"t":"Da, ovako govori Jahve nad Vojskama, Bog Izraelov, o posuđu koje preostade u Domu Jahvinu, u dvoru kralja judejskog, i u Jeruzalemu:"},{"v":22,"t":"'U Babilon će ih odnijeti i ondje će ostati sve do dana kad ja odem po njih - riječ je Jahvina. I ja ću sve to donijeti i postaviti na ovo mjesto!'”"}]},"28":{"hr":[{"v":1,"t":"Iste godine, u početku kraljevanja Sidkije, kralja judejskoga, četvrte godine, petog mjeseca, Hananija, sin Azurov, prorok rodom iz Gibeona, reče mi u Domu Jahvinu pred svim svećenicima i svim narodom:"},{"v":2,"t":"“Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Skršit ću jaram kralja babilonskoga."},{"v":3,"t":"Do dvije godine vratit ću na ovo mjesto sve posuđe Doma Jahvina koje je Nabukodonozor, kralj babilonski, odavde uzeo i odnio u Babilon."},{"v":4,"t":"A tako i Jekoniju, sina Jojakimova, kralja judejskoga, i sve izgnanike judejske, koji dospješe u Babilon, također ću vratiti na ovo mjesto - riječ je Jahvina - jer ću skršiti jaram kralja babilonskoga.'”"},{"v":5,"t":"Tada prorok Jeremija odgovori proroku Hananiji pred svećenicima i pred svim narodom koji bijahu u Domu Jahvinu."},{"v":6,"t":"Reče prorok Jeremija: “Amen! Učinio Jahve tako! Ispunio Jahve riječi koje si prorokovao i vratio ovamo sve posuđe iz Doma Jahvina i sve izgnanike iz Babilona."},{"v":7,"t":"Ali čujder i ovu riječ koju ću kazati na tvoje uši i na uši svega naroda."},{"v":8,"t":"Proroci koji su bili prije mene i tebe, odiskona prorokovahu mnogim moćnim zemljama i velikim kraljevstvima rat, glad, kugu."},{"v":9,"t":"Ali o proroku koji proriče mir možeš istom kad se ispuni njegova proročka riječ znati da ga je zaista Jahve poslao.”"},{"v":10,"t":"Tada prorok Hananija skide jaram s vrata proroka Jeremije i skrši ga."},{"v":11,"t":"I reče Hananija pred svim narodom: “Ovako govori Jahve: 'Evo, ovako ću - za dvije godine - skršiti jaram Nabukodonozora, kralja babilonskoga, s vrata svih naroda!'” Tada prorok Jeremija ode svojim putem."},{"v":12,"t":"A kad prorok Hananija skrši jaram s vrata proroka Jeremije, dođe riječ Jahvina Jeremiji:"},{"v":13,"t":"“Idi i ovako reci Hananiji: 'Ovako govori Jahve: Ti si skršio drveni jaram, ali ću ja mjesto njega načiniti željezni.'"},{"v":14,"t":"Jer ovako govori Jahve nad Vojskama, Bog Izraelov: 'Željezni ću jaram staviti oko vrata svih ovih naroda da ih podvrgnem Nabukodonozoru, kralju babilonskom, i služit će mu, jer ja sam njemu podložio čak i poljsku zvjerad!'”"},{"v":15,"t":"I prorok Jeremija reče proroku Hananiji: “Čuj me dobro, Hananija! Tebe nije poslao Jahve, a ti si u narodu pobudio varave nade."},{"v":16,"t":"Zato ovako govori Jahve: 'Gle, brišem te s lica zemlje! Umrijet ćeš još ove godine, jer si propovijedao pobunu protiv Jahve!'”"},{"v":17,"t":"I umrije prorok Hananija te godine u sedmom mjesecu."}]},"29":{"hr":[{"v":1,"t":"Evo, ovo su riječi poslanice koju prorok Jeremija iz Jeruzalema posla Ostatku izgnanstva - starješinama, svećenicima i prorocima i svemu preostalom narodu što ga Nabukodonozor iz Jeruzalema bijaše odveo u Babilon,"},{"v":2,"t":"pošto kralj Jekonija i kraljica-majka, dvorjanici, odličnici judejski i jeruzalemski, kovači i bravari ostaviše Jeruzalem."},{"v":3,"t":"Poslanica je poslana po Elasi, sinu Šafanovu, i Gemarji, sinu Hilkijinu, koje Sidkija, kralj judejski, posla u Babilon Nabukodonozoru, kralju babilonskom. Evo sadržaja:"},{"v":4,"t":"“Ovako govori Jahve nad Vojskama, kralj Izraelov: 'Svima izgnanicima koje odvedoh iz Jeruzalema u Babilon!"},{"v":5,"t":"Gradite kuće i nastanite se, sadite vrtove i uživajte urod njihov!"},{"v":6,"t":"Ženite se i rađajte sinove i kćeri! Ženite svoje sinove i udajite svoje kćeri da i oni rađaju sinove i kćeri! Množite se da se ne smanjite!"},{"v":7,"t":"Ištite mir zemlji u koju vas izagnah, molite se za nju Jahvi, jer na njezinu miru počiva i vaš mir!'"},{"v":8,"t":"Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Ne dajte da vas obmanjuju vaši proroci koji su među vama, vaši gataoci! Ne povodite se za snovima koje oni sanjaju!"},{"v":9,"t":"Jer oni vam laž prorokuju u moje ime, a ja ih nisam poslao' - riječ je Jahvina.”"},{"v":10,"t":"Jer ovako govori Jahve: 'Istom kad se Babilonu ispuni onih sedamdeset godina, ja ću vas pohoditi te vam ispuniti dobro obećanje da ću vas vratiti na ovo mjesto."},{"v":11,"t":"Jer ja znam svoje naume koje s vama namjeravam - riječ je Jahvina - naume mira, a ne nesreće: da vam dadnem budućnost i nadu."},{"v":12,"t":"Tada ćete me zazivati, dolaziti k meni, moliti mi se i ja ću vas uslišati."},{"v":13,"t":"Tražit ćete me i naći me jer ćete me tražiti svim srcem svojim."},{"v":14,"t":"I pustit ću da me nađete - riječ je Jahvina. Izmijenit ću udes vaš i sabrati vas iz svih naroda i sa svih mjesta kamo vas odagnah - riječ je Jahvina. I vratit ću vas na mjesto odakle vas u izagnanstvo odvedoh."},{"v":15,"t":"Istina, vi velite: 'Jahve nam podiže proroke u Babilonu.'"},{"v":16,"t":"Ovako govori Jahve kralju koji sjedi na prijestolju Davidovu, i svemu narodu koji živi u ovome gradu - braći vašoj što ne moradoše s vama u izgnanstvo."},{"v":17,"t":"Ovako govori Jahve nad Vojskama: “Evo šaljem na njih mač, glad i kugu; učinit ću da budu kao pokvarene smokve, tako loše da nisu za jelo."},{"v":18,"t":"I gonit ću ih mačem, glađu i kugom i učinit ću ih užasom svim kraljevstvima zemaljskim, prokletstvom, strahotom, ruglom i sramotom svim narodima kamo ih otjeram."},{"v":19,"t":"Jer ne poslušaše riječi mojih - riječ je Jahvina - premda sam im svejednako slao sluge svoje proroke, ali ih oni ne poslušaše - riječ je Jahvina."},{"v":20,"t":"Ali vi, izgnanici, koje poslah iz Jeruzalema u Babilon, poslušajte svi riječ Jahvinu!”"},{"v":21,"t":"Ovako govori Jahve nad Vojskama, kralj Izraelov, o Ahabu, sinu Kolajinu, i o Sidkiji, sinu Maasejinu, koji vam laž prorokuje u moje ime: “Evo, predajem ih u ruke Nabukodonozora, kralja babilonskoga, da ih pogubi vama na oči."},{"v":22,"t":"I njima će se kao kletvom proklinjati svi izgnanici koji su u Babilonu: 'Neka Jahve učini s tobom kao sa Sidkijom i Ahabom koje kralj babilonski ispeče na vatri"},{"v":23,"t":"jer u Izraelu počiniše sramotu čineći preljub sa ženama svojih bližnjih i govoreći u moje ime lažne riječi koje im ja nisam zapovjedio. Ja to znam, i svjedok sam tome' - riječ je Jahvina!”"},{"v":24,"t":"-"},{"v":25,"t":"A Šemaji ćeš Nehelamcu poručiti: “Ovako govori Jahve nad Vojskama, Bog Izraelov: Ti si u svoje ime poslao pisma svemu narodu koji je u Jeruzalemu, i svećeniku Sefaniji, sinu Maasejinu, i svim ostalim svećenicima:"},{"v":26,"t":"'Jahve te postavi svećenikom namjesto svećenika Jojade da paziš u Domu Jahvinu na svakog luđaka koji se gradi prorokom i da ga baciš u klade, sa željezom oko vrata."},{"v":27,"t":"Zašto, dakle, nisi spriječio Jeremiju iz Anatota, koji se među vama gradi prorokom?"},{"v":28,"t":"TÓa on nam je poslao poruku u Babilon: Dugo će još trajati: Gradite kuće i nastanite se! Sadite vrtove i uživajte urod njihov!'”"},{"v":29,"t":"Svećenik Sefanija pročita pismo proroku Jeremiji."},{"v":30,"t":"Tada dođe riječ Jahvina Jeremiji:"},{"v":31,"t":"“Pošalji svim izgnanicima ovu vijest: 'Ovako govori Jahve o Šemaji Nehelamcu: Jer vam Šemaja prorokuje te vam budi varave nade, premda ga ja nisam poslao,"},{"v":32,"t":"ovako govori Jahve: Kaznit ću Šemaju Nehelamca, njega i potomstvo njegovo: nitko mu neće preostati usred ovoga naroda da doživi sreću koju spremam narodu svojemu - riječ je Jahvina - jer je propovijedao pobunu protiv Jahve.'”"}]},"30":{"hr":[{"v":1,"t":"Riječ koju Jahve upravi Jeremiji:"},{"v":2,"t":"Ovako govori Jahve, Bog Izraelov: “Upiši u knjigu sve ove riječi koje ti govorim."},{"v":3,"t":"Jer evo dolaze dani - riječ je Jahvina - i promijenit ću udes naroda svoga Izraela i Judeje” - govori Jahve - “i vratit ću ih u zemlju koju u baštinu dadoh ocima njihovim.”"},{"v":4,"t":"Evo riječi što ih Jahve reče o Izraelu i o Judeji:"},{"v":5,"t":"Ovako govori Jahve: “Čujem krik užasa: strava je to, a ne mir."},{"v":6,"t":"Hajde, propitajte se i pogledajte: je li ikad muškarac rodio? A svi se muškarci za bedra hvataju kao porodilje! Zašto su sva lica izobličena i problijedjela?"},{"v":7,"t":"Jao, jer velik je dan ovaj, slična mu nÓe bÄi! Vrijeme je nevolje za Jakova, al' će se izbaviti iz nje."},{"v":8,"t":"Onoga dana - riječ je Jahve nad Vojskama - slomit ću jaram na njihovu vratu i lance ću njihove raskinuti. Više neće služiti tuđinu,"},{"v":9,"t":"već će služiti Jahvi, Bogu svojemu, i Davidu, kralju svome, koga ću im podići."},{"v":10,"t":"Ne boj se, Jakove, slugo moja - riječ je Jahvina - ne plaši se, Izraele! Jer evo, spasit ću te izdaleka i potomstvo tvoje iz zemlje izgnanstva. Jakov će se opet smiriti, spokojno će živjeti i nitko ga neće plašiti - riječ je Jahvina -"},{"v":11,"t":"jer ja sam s tobom da te izbavim. Zatrt ću narode među koje te prognah, a tebe neću sasvim uništiti; al' ću te kazniti po pravici, ne smijem te pustit' nekažnjena.”"},{"v":12,"t":"Uistinu, ovako govori Jahve: “Neiscjeljiva je rana tvoja, neprebolan polom tvoj."},{"v":13,"t":"Nema lijeka rani tvojoj i nikako da zaraste."},{"v":14,"t":"Zaboraviše te svi ljubavnici, više za te i ne pitaju! Jer po tebi ja udarih k'o što udara neprijatelj, kaznom krutom za bezakonje i za mnoge grijehe tvoje."},{"v":15,"t":"Zašto kukaš zbog rane svoje? Zar je neizlječiva tvoja bol? Zbog mnoštva bezakonja i grijeha silnih tvojih to ti učinih."},{"v":16,"t":"Al' i oni što te žderu bit će prožderani, u ropstvo će svi dušmani tvoji; pljačkaši tvoji bit će opljačkani, i koji te plijeniše bit će oplijenjeni."},{"v":17,"t":"[17b] Zvahu te 'Protjeranom' i 'Sionkom za koju nitko ne pita'. [17a] Al' ja ću te iscijeliti, rane ti zaliječiti” - riječ je Jahvina."},{"v":18,"t":"Ovako govori Jahve: “Evo, izmijenit ću udes šatora Jakovljevih, smilovat ću se na stanove njegove: na razvalinama njegovim bit će opet grad sazidan, i dvori će stajati na starome mjestu."},{"v":19,"t":"Iz njih će se čuti hvalospjev, i glasovi radosni. Umnožit ću ih i više im se neće smanjiti broj, ugled ću im dati i više ih neće prezirati."},{"v":20,"t":"Sinovi njihovi bit će mi kao nekoć, zajednica njina preda mnom će čvrsto stajati, a kaznit ću sve njihove ugnjetače."},{"v":21,"t":"Glavar njihov iz njih će niknuti, vladar njihov isred njih će izaći. Pustit ću ga k sebi da mi se približi - jer tko da se usudi sam preda me!” - riječ je Jahvina."},{"v":22,"t":"“I vi ćete biti moj narod, a ja vaš Bog."},{"v":23,"t":"Gle, nevrijeme Jahvino, jarost provaljuje, razmahuje se vihor silan, i svaljuje na glave bezbožničke."},{"v":24,"t":"Jahvin se gnjev neće stišati dok on ne izvrši i ne ispuni naume srca svojega. U dane posljednje jasno ćete to razumjeti."}]},"31":{"hr":[{"v":1,"t":"“U ono vrijeme - riječ je Jahvina - bit ću Bog svim plemenima Izraelovim i oni će biti narod moj.”"},{"v":2,"t":"Ovako govori Jahve: “Nađe milost u pustinji narod koji uteče maču: Izrael ide u svoje prebivalište."},{"v":3,"t":"Iz daljine mu se Jahve ukaza: Ljubavlju vječnom ljubim te, zato ti sačuvah milost."},{"v":4,"t":"Opet ću te sazdati, i bit ćeš sazdana, djevice Izraelova. Opet ćeš se resit' bubnjićima, u veselo kolo hvatati."},{"v":5,"t":"Opet ćeš saditi vinograde na brdima Samarije: koji nasade posade, oni će i trgati."},{"v":6,"t":"Jer dolazi dan te će stražari vikati na brdu efrajimskom: 'Na noge! Na Sion se popnimo, k Jahvi, Bogu svojemu!'”"},{"v":7,"t":"Jer ovako govori Jahve: “Kličite od radosti Jakovu, pozdravite burno prvaka naroda! Neka se ori vaš glas! Objavite slavopojkom: Jahve spasi narod svoj, Ostatak Izraelov!"},{"v":8,"t":"Evo, ja ih vodim iz zemlje sjeverne, skupljam ih s krajeva zemlje: s njima su slijepi i hromi, trudnice i rodilje: vraća se velika zajednica."},{"v":9,"t":"Evo, u suzama pođoše, utješene sad ih vraćam! Vodit ću ih kraj potočnih voda, putem ravnim kojim neće posrnuti, jer ja sam otac Izraelu, Efrajim je moj prvenac.”"},{"v":10,"t":"Čujte, o narodi, riječ Jahvinu, objavite je širom dalekih otoka: “Onaj što rasprši Izraela, opet ga sabire i čuva ga k'o pastir stado svoje!”"},{"v":11,"t":"Jer Jahve oslobodi Jakova, izbavi ga iz ruku jačeg od njega."},{"v":12,"t":"I oni će, radosno kličući, na vis sionski da se naužiju dobara Jahvinih: žita, ulja, mladog vina, jagnjadi i teladi, duša će im biti kao vrt navodnjen, nikad više neće ginuti."},{"v":13,"t":"Djevojke će se veselit' u kolu, mlado i staro zajedno, jer ću im tugu u radost pretvoriti, utješit ću ih i razveselit' nakon žalosti."},{"v":14,"t":"Pretilinom ću im okrijepiti svećenstvo i narod svoj nasititi dobrima” - riječ je Jahvina."},{"v":15,"t":"Ovako govori Jahve: “Čuj! U Rami se kukanje čuje i gorak plač: Rahela oplakuje sinove svoje, i neće da se utješi za djecom, jer njih više nema.”"},{"v":16,"t":"Ovako govori Jahve: “Prestani kukati, otari suze u očima! Patnje će tvoje biti nagrađene: oni će se vratiti iz zemlje neprijateljske."},{"v":17,"t":"Ima nade za tvoje potomstvo - riječ je Jahvina - sinovi tvoji vratit će se u svoj kraj."},{"v":18,"t":"Dobro čujem Efrajimov jecaj: 'Ti me pokara, i ja se popravih kao june još neukroćeno. Obrati me, da se obratim, jer ti si, Jahve, Bog moj."},{"v":19,"t":"Odvratih se od tebe, ali se pokajah, uvijek, i sad se u slabine tučem. Stidim se i crvenim, jer nosim sramotu mladosti svoje!'”"},{"v":20,"t":"“Zar mi je Efrajim sin toliko drag, dijete najmilije? Jer koliko god mu prijetim, bez prestanka živo na njega mislim i srce mi dršće za njega od nježne samilosti” - riječ je Jahvina."},{"v":21,"t":"“Postavi putokaze, podigni stupove! Sjeti se ceste, puta kojim si prošla. I vrati se, djevice Izraelova, vrati se u gradove svoje!"},{"v":22,"t":"Dokle ćeš još oklijevati, kćeri odmetnice? Jer Jahve stvori nešto novo na zemlji: Žena će okružiti Muža.”"},{"v":23,"t":"Ovako govori Jahve nad Vojskama, Bog Izraelov: “U zemlji Judinoj, kad promijenim njezinu sudbinu, u njezinim će se gradovima ovako govoriti: 'Blagoslovio te Jahve, prebivalište Pravednosti, Goro sveta!'”"},{"v":24,"t":"“I u njoj će se opet nastaniti Judeja sa svim svojim gradovima, ratari i oni što idu za stadima,"},{"v":25,"t":"jer ja ću okrijepiti dušu iscrpljenu, obilno nahraniti dušu klonulu."},{"v":26,"t":"Kao ono: 'Čim se probudih, pogledah: sladak li bijaše sanak moj!'”"},{"v":27,"t":"“Evo dolaze dani - riječ je Jahvina - kad ću u domu Izraelovu i u domu Judinu posijati sjeme čovječje i sjeme životinjsko."},{"v":28,"t":"I kao što sam nekoć bdio da ih iščupam, razvalim, istrijebim, zatrem i nesreću na njih svalim, tako ću sada brižno bdjeti da ih podignem i posadim."},{"v":29,"t":"U one dane neće se više govoriti: 'Oci jedoše kiselo grožđe, a sinovima zubi trnu.'"},{"v":30,"t":"Nego će svatko umrijeti zbog vlastite krivice. I onomu koji bude jeo kiselo grožđe zubi će trnuti.”"},{"v":31,"t":"“Evo dolaze dani - riječ je Jahvina - kad ću s domom Izraelovim i s domom Judinim sklopiti Novi savez."},{"v":32,"t":"Ne Savez kakav sam sklopio s ocima njihovim u dan kad ih uzeh za ruku da ih izvedem iz zemlje egipatske, Savez što ga oni razvrgoše premda sam ja gospodar njihov - riječ je Jahvina."},{"v":33,"t":"Nego, ovo je Savez što ću ga sklopiti s domom Izraelovim poslije onih dana - riječ je Jahvina: Zakon ću svoj staviti u dušu njihovu i upisati ga u njihovo srce. I bit ću Bog njihov, a oni narod moj."},{"v":34,"t":"I neće više učiti drug druga ni brat brata govoreći: 'Spoznajte Jahvu!' nego će me svi poznavati, i malo i veliko - riječ je Jahvina - jer ću oprostiti bezakonje njihovo i grijeha se njihovih neću više spominjati.”"},{"v":35,"t":"Ovako govori Jahve, koji daje da sunce sjaje danju, a mjesec i zvijezde da svijetle noću, koji burka more da mu valovi buče - ime mu je Jahve nad Vojskama:"},{"v":36,"t":"“Ako se ikad ti zakoni poremete preda mnom - riječ je Jahvina - onda će i potomstvo Izraelovo prestati da bude narod pred licem mojim zauvijek!"},{"v":37,"t":"Ako se mogu izmjeriti nebesa gore, i dolje istražiti temelji zemlje, onda ću i ja odbaciti potomstvo Izraelovo zbog svega što počiniše” - riječ je Jahvina."},{"v":38,"t":"“Evo dolaze dani - riječ je Jahvina - kada će grad Jahvin biti opet sazidan, od Kule Hananelove do Vrata ugaonih."},{"v":39,"t":"I još će se dalje protegnuti mjerničko uže, pravo do brežuljka Gareba, a onda okrenuti prema Goi."},{"v":40,"t":"I sva dolina trupla i pepela, i sva polja do potoka Kidrona, do ugla Konjskih vrata na istoku, bit će svetinja Jahvina. I neće više biti razaranja ni prokletstva.”"}]},"32":{"hr":[{"v":1,"t":"Riječ koju Jahve uputi Jeremiji desete godine Sidkije, kralja judejskoga, to jest osamnaeste godine Nabukodonozorove."},{"v":2,"t":"U to vrijeme vojska kralja babilonskoga opsjedaše Jeruzalem, a prorok Jeremija bijaše zatvoren u tamničkom dvorištu u dvoru judejskoga kralja."},{"v":3,"t":"Sidkija, kralj judejski, bijaše ga ondje zatvorio, prigovoriv mu: “Zašto si prorokovao: 'Ovako govori Jahve: Gle, grad ću ovaj predati u ruke kralju babilonskom da ga osvoji;"},{"v":4,"t":"a Sidkija, kralj judejski, neće umaći sili kaldejskoj, nego će biti predan u ruke kralja babilonskoga - usta u usta s njim će govoriti, oči u oči njega vidjeti."},{"v":5,"t":"Sidkiju će odvesti u Babilon i ondje će ostati dok ga ne pohodim - riječ je Jahvina! I ako se budete borili protiv Kaldejaca, nećete uspjeti!'”"},{"v":6,"t":"Tada reče Jeremija: “Dođe mi riječ Jahvina:"},{"v":7,"t":"'Uskoro će doći k tebi Hanamel, sin tvoga strica Šaluma, da ti kaže: Kupi njivu moju u Anatotu; ti imaš rodbinsko pravo da je kupiš!'"},{"v":8,"t":"Kako je Jahve navijestio, k meni dođe moj stričević Hanamel u tamničko dvorište i reče mi: 'De kupi moju njivu u Anatotu, jer ti imaš pravo na posjed i rodbinsko pravo da je kupiš! Kupi je!' I tada spoznah da to bijaše riječ Jahvina."},{"v":9,"t":"Kupih, dakle, tu njivu od stričevića Hanamela iz Anatota te mu izmjerih u novcu sedamnaest šekela srebra."},{"v":10,"t":"Napišem ugovor, udarim pečat, pozovem svjedoke i izmjerim novac na tezulji."},{"v":11,"t":"Zatim uzmem kupovni ugovor, zapečaćen prema propisu i uredbama,"},{"v":12,"t":"predam kupovni ugovor Baruhu, sinu Mahsejeva sina Nerije. Nazočni su bili: moj stričević Hanamel, svjedoci što su potpisali kupovni ugovor i svi Judejci koji su se našli u tamničkom dvorištu."},{"v":13,"t":"Tada pred njima zapovjedim Baruhu:"},{"v":14,"t":"'Ovako govori Jahve nad Vojskama, Bog Izraelov: Uzmi ove isprave, ovaj kupovni ugovor, zapečaćeni i otvoreni, i stavi ih u glinenu posudu da se zadugo sačuvaju."},{"v":15,"t":"Jer ovako govori Jahve nad Vojskama, Bog Izraelov: Još će se u ovoj zemlji kupovati i kuće, i njive, i vinogradi!'”"},{"v":16,"t":"Pošto kupovni ugovor predadoh Nerijinu sinu Baruhu, pomolih se Jahvi:"},{"v":17,"t":"“O, Jahve, Gospode! Ti stvori nebo i zemlju snagom velikom, rukom uzdignutom! Ništa tebi nije nemoguće!"},{"v":18,"t":"Tisućama iskazuješ milost, a krivnju otaca osvećuješ na djeci, potomcima njihovim. Bože veliki i moćni, kome je ime Jahve nad Vojskama!"},{"v":19,"t":"Velik si u svojim naumima, silan u svojim djelima! Oči tvoje bde nad svim putovima ljudskim da naplatiš svakome prema putu njegovu i prema plodu djela njegovih!"},{"v":20,"t":"Ti koji si činio znamenja i čudesa u zemlji egipatskoj i u Izraelu, i među svim ljudima sve do danas,"},{"v":21,"t":"ti si izveo svoj narod izraelski iz zemlje egipatske znamenjima i čudesima, rukom moćnom i mišicom podignutom, strahotama velikim."},{"v":22,"t":"Zatim im dade svu ovu zemlju koju si zakletvom obećao ocima njihovim, zemlju u kojoj teče med i mlijeko."},{"v":23,"t":"I oni je zaposjedoše; ali nisu slušali glasa tvojega niti su hodili putem Zakona tvojega. Ništa ne učiniše od onog što im ti naredi; zato si dozvao na njih sve ove nevolje."},{"v":24,"t":"Gle, nasipi se već primakoše gradu, i bit će osvojen, i grad će pasti u ruke Kaldejcima koji na nj navaljuju mačem, glađu i kugom. Čime si prijetio, evo dolazi. I sam vidiš."},{"v":25,"t":"A ti mi, Jahve Gospode moj, reče: 'Kupi novcem njivu i pozovi svjedoke', a grad je već predan u ruke Kaldejcima!”"},{"v":26,"t":"Tada mi dođe riječ Jahvina:"},{"v":27,"t":"“Gle, ja sam Jahve, Bog svakoga tijela! Meni ništa nije nemoguće!"},{"v":28,"t":"Zato - veli Jahve - grad ovaj predajem u ruke Kaldejaca i u ruke kralja babilonskoga, koji će ga zauzeti."},{"v":29,"t":"Ući će u nj Kaldejci koji se bore protiv ovoga grada, ognjem će ga uništiti i spaliti ga zajedno s kućama kojima su na krovovima Baalu palili tamjan i lijevali ljevanice tuđim bogovima, mene gnjeveći."},{"v":30,"t":"Jer sinovi Izraelovi i sinovi Judini od mladosti čine samo zlo pred mojim očima. Doista, sinovi Izraelovi bez prestanka me gnjeve djelima ruku svojih - riječ je Jahvina."},{"v":31,"t":"Grad ovaj, doista, samo mi je na gnjev i srdžbu otkako je sagrađen pa do dana današnjega te ga moram ukloniti ispred lica svojega"},{"v":32,"t":"zbog svega bezakonja što ga sinovi Izraelovi i sinovi Judini počiniše, gnjeveći me - oni i kraljevi njihovi, knezovi i svećenici i proroci, Judejci i Jeruzalemci."},{"v":33,"t":"Okretahu mi leđa, a ne lice svoje, iako se neumorno trudih da ih poučim, ali me ne slušaše niti nauk moj primiše."},{"v":34,"t":"Postaviše grozote u Dom koji se mojim zove imenom da ga oskvrnu."},{"v":35,"t":"Baalu podigoše uzvišice u Dolini Ben Hinomu, i sinove i kćeri svoje Moleku kroz oganj provodiše - što im ja nikad ne zapovjedih; ni na um mi ne pade da bi činili takve gadosti niti da bih Judu pustio u takav grijeh.”"},{"v":36,"t":"Ipak, ovako govori Jahve, Bog Izraelov, o tom gradu za koji vi velite da će od mača, gladi i kuge pasti u ruke kralju babilonskom:"},{"v":37,"t":"“Evo, ja ću ih sabrati iz svih zemalja u koje ih prognah - u gnjevu i jarosti svojoj - i vratit ću ih na ovo mjesto da ovdje spokojno žive."},{"v":38,"t":"I oni će biti narod moj, a ja, ja ću biti Bog njihov."},{"v":39,"t":"I dat ću im srce jedno i put jedan, da bi me se bojali u sve dane, na sreću svoju i djece svoje."},{"v":40,"t":"I sklopit ću s njima Savez vječan, nikad se više neću odvratiti od njih i uvijek ću im činiti dobro; usadit ću im u srce svoj strah, da se nikad više ne odmetnu od mene."},{"v":41,"t":"I radovat ću se čineći im dobro; i čvrsto ću ih zasaditi u ovoj zemlji, svim srcem svojim, svom dušom svojom.”"},{"v":42,"t":"Jer ovako govori Jahve: “Kao što sam na ovaj narod doveo svu ovu strašnu nesreću, tako ću na njih dovesti svu sreću koju im obrekoh."},{"v":43,"t":"Da, opet će se kupovati njive u ovoj zemlji o kojoj vi velite: 'Ova je pustinja, bez čovjeka i živinčeta, predana na milost i nemilost Kaldejcima!'"},{"v":44,"t":"Njive će se za novac kupovati, pisat će se i pečatiti kupovni ugovori, pozivat će se svjedoci u zemlji Benjaminovoj i u okolici Jeruzalema. U gradovima Judinim i u gradovima Gorja, Šefele, Negeba, jer ću promijeniti udes njihov” - riječ je Jahvina."}]},"33":{"hr":[{"v":1,"t":"Dok je Jeremija bio još zatvoren u tamničkom dvorištu, i drugi mu put dođe riječ Jahvina:"},{"v":2,"t":"“Ovako govori Jahve, koji stvori zemlju, oblikova je i učvrsti - ime mu je Jahve!"},{"v":3,"t":"Zazovi me, i odazvat ću ti se i objavit ću ti velike i nedokučive tajne o kojima ništa ne znaš."},{"v":4,"t":"Jer ovako govori Jahve, Bog Izraelov, o kućama ovoga grada i o dvorima kraljeva judejskih, porušenim zbog nasipa i mača,"},{"v":5,"t":"i o onima što zameću borbu s Kaldejcima da napune svoje kuće tjelesima ljudi koje pobih u srdžbi i jarosti svojoj, i odvratih lice svoje od ovoga grada zbog njihove opakosti."},{"v":6,"t":"Evo, ja ću zaliječiti njihovu ranu, ja ću ih iscijeliti i ozdraviti i pružiti im obilje istinskoga mira."},{"v":7,"t":"Promijenit ću udes zemlje Judine i Jeruzalema i podići ću ih da budu kao nekoć."},{"v":8,"t":"Očistit ću ih od svakoga grijeha kojim sagriješiše protiv mene i oprostit ću im sve krivice koje mi skriviše odmetnuv se od mene."},{"v":9,"t":"I Jeruzalem će mi biti na radost, na hvalu i čast pred svim narodima svijeta: kad čuju za sve dobro kojim ću ih nadijeliti, divit će se i čuditi svoj onoj sreći i miru što ću im ja dati.”"},{"v":10,"t":"Ovako govori Jahve: “Na ovome mjestu o kojemu vi velite: 'To je pustinja bez čovjeka i bez živinčeta' - u gradovima judejskim i po opustošenim ulicama jeruzalemskim opet će se oriti"},{"v":11,"t":"poklici radosti, poklici zaručnika i zaručnice, poklici onih koji će u Domu Jahvinu prinositi žrtve zahvalnice pjevajući: 'Hvalite Jahvu nad Vojskama, jer je dobar Jahve - vječna je ljubav njegova!' Jer ja ću obnoviti zemlju da bude kao nekoć” - riječ je Jahvina."},{"v":12,"t":"Ovako govori Jahve nad Vojskama: “Na ovome mjestu koje je sada pusto, bez čovjeka i bez živinčeta, i u svim gradovima opet će biti pašnjaci za pastire što odmaraju stada svoja."},{"v":13,"t":"U gradovima Gorja, i u gradovima Šefele, i u gradovima Negeba, u kraju Benjaminovu, u okolici Jeruzalema i u gradovima Judinim opet će prolaziti ovce ispod ruke pastira koji će ih brojiti” - riječ je Jahvina."},{"v":14,"t":"“Evo, dolaze dani - riječ je Jahvina - kad ću ispuniti dobro obećanje što ga dadoh domu Izraelovu i domu Judinu:"},{"v":15,"t":"U one dane i u vrijeme ono podići ću Davidu izdanak pravedni; on će zemljom vladati po pravu i pravici."},{"v":16,"t":"U one dane Judeja će biti spašena, Jeruzalem će živjeti spokojno. A grad će se zvati: 'Jahve, Pravda naša.'"},{"v":17,"t":"Jer ovako govori Jahve: “Nikada Davidu neće nestati potomka koji će sjediti na prijestolju doma Izraelova."},{"v":18,"t":"I nikada neće levitima i svećenicima nestati potomaka koji će služiti preda mnom i prinositi paljenice, kaditi prinosnice i prikazivati klanice u sve dane.”"},{"v":19,"t":"I dođe riječ Jahvina Jeremiji:"},{"v":20,"t":"Ovako govori Jahve: “Ako možete razvrći savez moj s danom i savez moj s noći, tako da ni dana ni noći više ne bude u pravo vrijeme,"},{"v":21,"t":"moći će se raskinuti i Savez moj sa slugom mojim Davidom te više neće imati sina koji bi kraljevao na prijestolju njegovu i s levitima i svećenicima koji mi služe."},{"v":22,"t":"Kao što se vojska nebeska ne može izbrojiti ni izmjeriti pijesak morski, tako ću umnožiti potomstvo sluge svojega Davida i levite i svećenike koji mi služe.”"},{"v":23,"t":"I dođe riječ Jahvina Jeremiji:"},{"v":24,"t":"“Nisi li opazio što ovi ljudi govore: 'Jahve je odbacio obadva plemena koja je bio sebi izabrao?' I s prezirom poriču narod moj kao da mi više nije narod.”"},{"v":25,"t":"Ovako govori Jahve: “Da ne sklopih saveza svojega s danom i noći i da ne postavih zakone nebu i zemlji,"},{"v":26,"t":"mogao bih odbaciti potomstvo Jakova i Davida, sluge svojega, da više ne uzimam potomka njihova za vladara nad potomstvom Abrahamovim, Izakovim i Jakovljevim, kad promijenim udes njihov i kad im se smilujem.”"}]},"34":{"hr":[{"v":1,"t":"Riječ koju Jahve uputi Jeremiji kad Nabukodonozor, kralj babilonski, i sva njegova vojska, i sva kraljevstva pod njegovom vlašću, i svi narodi navališe na Jeruzalem i na sve gradove njegove."},{"v":2,"t":"Ovako govori Jahve, Bog Izraelov: “Idi i govori sa Sidkijom, kraljem judejskim, i reci mu: Ovako govori Jahve: 'Evo, predajem ovaj grad u ruke kralja babilonskoga da ga on ognjem spali."},{"v":3,"t":"Ni ti nećeš ruci njegovoj umaći. Da, bit ćeš uhvaćen i predat će te u njegove ruke; oči u oči gledat ćeš kralja babilonskoga, usta u usta on će s tobom govoriti i bit ćeš odveden u Babilon.'"},{"v":4,"t":"Ali čuj riječ Jahvinu, Sidkija, kralju judejski! Ovo ti poručuje Jahve: 'Nećeš od mača poginuti,"},{"v":5,"t":"umrijet ćeš u miru! I kao što su tvoje očeve i kraljeve tvoje prethodnike okadili, i tebe će okaditi i naricat će za tobom: 'Jao Gospodaru!' Ja ti to govorim' - riječ je Jahvina."},{"v":6,"t":"I prorok Jeremija poruči sve ove riječi Sidkiji, kralju judejskom u Jeruzalemu,"},{"v":7,"t":"dok je vojska kralja babilonskoga navaljivala na Jeruzalem i na preostale gradove Judine - na Lakiš i Azeku, jer još samo oni preostadoše od judejskih utvrđenih gradova."},{"v":8,"t":"Riječ koju Jahve uputi Jeremiji, pošto je kralj Sidkija sa svekolikim narodom jeruzalemskim sklopio savez da im proglasi slobodu,"},{"v":9,"t":"da svaki pusti na slobodu svoga roba Hebreja i svoju robinju Hebrejku te da više ni u koga ne bude Hebrej, brat njegov, kao rob."},{"v":10,"t":"I svi odličnici i sav narod koji uđoše u ovaj savez pristadoše te svaki pusti na slobodu roba svoga i svoju ropkinju da im više ne robuju. Pristadoše, dakle, i pustiše ih."},{"v":11,"t":"A potom se okrenuše i uzeše opet svoje robove i ropkinje koje bijahu oslobodili pa ih prisiliše da im opet robuju."},{"v":12,"t":"Tada Jahve uputi riječ Jeremiji govoreći:"},{"v":13,"t":"Ovako govori Jahve, Bog Izraelov: “Ja sam sklopio Savez s ocima vašim u dan kada ih izvedoh iz Egipta, iz zemlje ropstva, govoreći:"},{"v":14,"t":"'Nakon sedam godina neka svaki od vas pusti na slobodu brata svoga Hebreja koji mu se prodao i šest godina kao rob služio.' Ali me vaši oci ne poslušaše i ne htjedoše me čuti."},{"v":15,"t":"A vi se bijaste obratili i učinili što je pravo u očima mojim, proglasivši slobodu za svakoga bližnjega svoga i preda mnom ste sklopili savez u Domu koji se zove mojim imenom."},{"v":16,"t":"A zatim se okrenuste i oskvrnuste ime moje, jer je svaki od vas opet uveo svoga roba i ropkinju koje ste već bili oslobodili, i ponovo ste ih prisilili da vam robuju.”"},{"v":17,"t":"Zato ovako govori Jahve: “Vi me ne poslušaste da proglasite slobodu subratu svojemu i bližnjemu. I zato, evo, i ja proglašavam protiv vas slobodu - riječ je Jahvina - maču, kugi i gladi, i učinit ću vas strašilom svim kraljevstvima zemlje."},{"v":18,"t":"A s ljudima koji razvrgoše Savez moj i ne ispuniše saveza obećana pred mojim licem postupit ću kao s teletom što ga nadvoje rasjekoše te između tih pola prođoše."},{"v":19,"t":"Knezove Judeje i Jeruzalema, dvorjane, svećenike i sav narod zemlje što prođoše između pola telećih"},{"v":20,"t":"predat ću u ruke dušmana koji im rade o glavi, a njihova trupla bit će hrana pticama nebeskim i zvijerima zemaljskim."},{"v":21,"t":"Sidkiju, kralja judejskoga, i njegove knezove predat ću u ruke dušmana koji im rade o glavi i u ruke vojske kralja babilonskoga, koja se od vas bila povukla."},{"v":22,"t":"Evo, ja ću im zapovjediti - riječ je Jahvina - i vratit ću ih na ovaj grad, i navalit će na nj, osvojiti ga i ognjem spaliti. A gradove judejske obratit ću u pustinju nenastanjenu.”"}]},"35":{"hr":[{"v":1,"t":"Jahve uputi riječ Jeremiji u dane Jojakima, sina Jošijina, kralja judejskoga:"},{"v":2,"t":"“Idi u zajednicu Rekabovaca, govori s njima i dovedi ih u Dom Jahvin, u jednu od dvorana, i daj im vina.”"},{"v":3,"t":"Tada dovedoh Jaazaniju, sina Habasinijina sina Jeremije, njegovu braću i sve sinove njegove i sav dom Rekabovaca"},{"v":4,"t":"i dovedoh ih u Dom Jahvin, u dvoranu čovjeka Božjega Ben Johanana, sina Jigdalijina, koja je kraj dvorane kneževske, a nad dvoranom vratara Maaseje, sina Šalumova."},{"v":5,"t":"Zatim stavih pred sinove doma Rekabova krčage pune vina i čaše te im rekoh: “Pijte vina!”"},{"v":6,"t":"Ali oni odgovoriše: “Ne pijemo vina, jer nam je otac naš Jonadab, sin Rekabov, zapovjedio: 'Ne smijete nikada piti vina, ni vi ni sinovi vaši."},{"v":7,"t":"Niti smijete graditi kućÄa, niti sijati sjemena ni saditi vinogradÄa, niti ih posjedovati, nego provodite sav život pod šatorima, da dugo živite u zemlji gdje kao stranci boravite.'"},{"v":8,"t":"I mi poslušasmo glas oca Jonadaba, sina Rekabova, u svem što nam je zapovjedio: da nikad vina ne pijemo, ni mi ni žene naše, niti sinovi naši, ni kćeri naše,"},{"v":9,"t":"da ne gradimo kuća, ni da posjedujemo vinograda ni polja zasijanih,"},{"v":10,"t":"da stanujemo pod šatorima i držimo se poslušno svega što nam zapovjedi naš otac Jonadab."},{"v":11,"t":"Samo kada je Nabukodonozor, kralj babilonski, krenuo protiv ove zemlje, rekosmo: 'Hajdemo, pođimo u Jeruzalem da izbjegnemo vojsku kaldejsku i vojsku aramejsku!' I tako sada živimo u Jeruzalemu.”"},{"v":12,"t":"Tada dođe riječ Jahvina Jeremiji:"},{"v":13,"t":"Ovako govori Jahve nad Vojskama, kralj Izraelov: “Idi i objavi Judejcima i Jeruzalemcima: 'Zar nećete primiti nauka moga i poslušati riječi moje?' - riječ je Jahvina. -"},{"v":14,"t":"'Ispunjuju se riječi Jonadaba, sina Rekabova, koji je sinovima svojim zabranio da piju vina, i do dana današnjega nitko ga nije pio, jer oni slušaju riječ svoga oca. A ja sam vam jednako govorio, ali me niste slušali."},{"v":15,"t":"I slao sam bez prestanka k vama sluge svoje, proroke, da vam propovijedaju: 'Vratite se svaki sa svoga opakog puta, popravite djela svoja i ne trčite za tuđim bogovima da im služite, pa ćete ostati u zemlji koju dadoh vama i ocima vašim'; ali ne prikloniste uha svojega i ne poslušaste me."},{"v":16,"t":"Sinovi Jonadaba, sina Rekabova, držahu se zapovijedi koju im dade otac njihov. Ali mene ovaj narod ne sluša.'"},{"v":17,"t":"Zato govori Jahve nad Vojskama, Bog Izraelov: 'Evo, navući ću na sve Jeruzalemce sve one nevolje kojima sam im zaprijetio, jer sam im govorio, a oni me ne slušahu, dozivao ih, ali se oni ne odazivahu.'”"},{"v":18,"t":"Zajednici Rekabovaca Jeremija reče: “Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Jer ste slušali zapovijedi svoga oca Jonadaba i držali se svih naredaba i činili sve što vam je on zapovjedio,"},{"v":19,"t":"zato - ovako govori Jahve nad Vojskama, kralj Izraelov - Jonadabu, sinu Rekabovu, nikad neće ponestati potomka koji će stajati pred licem mojim u sve dane.'”"}]},"36":{"hr":[{"v":1,"t":"Četvrte godine Jojakima, sina Jošijina, kralja judejskoga, uputi Jahve Jeremiji ovu riječ:"},{"v":2,"t":"“Uzmi svitak i zapiši na nj sve riječi koje ti kazah o Jeruzalemu, Judeji i svim narodima, od dana kad ti počeh govoriti, od dana Jošijinih do dana današnjega."},{"v":3,"t":"Možda će čuti dom Judin o svim nesrećama što sam ih naumio oboriti na njih te će se vratiti svaki sa svoga zlog puta, a ja ću im oprostiti krivicu i grijeh njihov.”"},{"v":4,"t":"Tada Jeremija dozva Baruha, sina Nerijina, i Baruh napisa na svitak, po kazivanju Jeremijinu, sve riječi koje mu Jahve bijaše objavio."},{"v":5,"t":"Tada Jeremija naredi Baruhu: “Meni nije slobodno te ne mogu poći u Dom Jahvin."},{"v":6,"t":"Idi ti te na dan posta u Domu Jahvinu čitaj narodu riječi Jahvine iz svitka što si ga po mojem kazivanju napisao. Pročitaj ih i svim Judejcima koji su došli iz svojih gradova."},{"v":7,"t":"Možda će se vapaji njihovi vinuti k Jahvi i možda će se obratiti svatko sa zloga puta svojega; jer je velik bijes i srdžba kojima Jahve prijeti ovom narodu.”"},{"v":8,"t":"I Baruh, sin Nerijin, učini sve kako mu prorok Jeremija bijaše zapovjedio da pročita riječi Jahvine u Domu Jahvinu."},{"v":9,"t":"U petoj godini Jojakima, sina Jošijina, kralja judejskoga, mjeseca devetoga, pozvaše na post pred Jahvu sav narod jeruzalemski i sav narod što mogaše stići iz gradova judejskih u Jeruzalem."},{"v":10,"t":"Baruh svemu narodu pročita riječi Jeremije iz svitka u Domu Jahvinu, u dvorani Gemarje, sina pisara Šafana, u gornjem predvorju pred Novim vratima Jahvina Doma."},{"v":11,"t":"A kad Mikaj, sin Šafanova sina Gemarje, ču iz knjige sve Jahvine riječi,"},{"v":12,"t":"siđe u kraljevski dvor u sobu pisarovu, gdje upravo sjeđahu svi dostojanstvenici: pisar Elišama, Delaja, sin Šemajin, Elnatan, sin Akborov, Gemarja, sin Šafanov, Sidkija, sin Hananijin, i svi drugi dostojanstvenici."},{"v":13,"t":"Mikaj im kaza sve riječi što ih bijaše čuo kad ih je Baruh narodu čitao iz knjige."},{"v":14,"t":"Tada dostojanstvenici poslaše Jehudija, sina Netanijina, i Šelemju, sina Kušijeva, Baruhu da mu kažu: “Uzmi u ruke svitak iz kojega si čitao narodu i dođi!” Tada Baruh, sin Nerijin, uze svitak u ruke i dođe k njima."},{"v":15,"t":"Oni mi rekoše: “Hajde, sjedi i pročitaj nam!” I Baruh im pročita."},{"v":16,"t":"Kad čuše sve one riječi, uplašeno se pogledaše i rekoše Baruhu: “Moramo sve to kazati kralju.”"},{"v":17,"t":"I upitaše Baruha: “Hajde, objasni nam kako ti napisa sve te riječi.”"},{"v":18,"t":"Baruh će njima: “Jeremija mi je sve te riječi u pero kazivao, a ja sam ih crnilom u knjigu zapisao.”"},{"v":19,"t":"Tada dostojanstvenici rekoše Baruhu: “Idi i sakrijte se, ti i Jeremija; nitko da ne zna gdje ste.”"},{"v":20,"t":"I, pohranivši svitak u dvorani pisara Elišame, pođoše kralju u dvorsko predvorje i sve mu ispripovjediše."},{"v":21,"t":"Kralj posla Jehudija da donese svitak: on ga donese iz sobe pisara Elišame i pročita ga kralju i dostojanstvenicima koji stajahu oko njega."},{"v":22,"t":"Kralj je sjedio u zimskim odajama - bijaše to u devetom mjesecu - a pred njim stajaše ražarena žeravnica."},{"v":23,"t":"I kako bi Jehudi pročitao tri-četiri stupca, kralj bi ih rezao pisarskim perorezom i bacao u vatru na žeravnice sve dok cio svitak ne bi uništen u vatri žeravnice."},{"v":24,"t":"Ni kralj ni njegove sluge ne prestrašiše se niti razderaše haljina kad čuše te riječi,"},{"v":25,"t":"pa ipak Elnatan, Delaja i Gemarja moljahu kralja da ne spali svitak, ali on ih ne posluša."},{"v":26,"t":"Tada kralj zapovjedi kraljeviću Jerahmeelu i Seraji, sinu Azrielovu, i Šelemji, sinu Abdeelovu, da uhvate pisara Baruha i proroka Jeremiju. Ali ih Jahve bijaše sakrio."},{"v":27,"t":"Pošto je dakle kralj spalio svitak s riječima što ih Baruh bijaše zapisao po Jeremijinu kazivanju, dođe riječ Jahvina Jeremiji:"},{"v":28,"t":"“Uzmi drugi svitak i upiši u nj sve one riječi što bijahu na prvom svitku koji je Jojakim, kralj judejski, spalio."},{"v":29,"t":"A protiv Jojakima, kralja judejskoga, ovako reci: Ovako govori Jahve: Spalio si svitak govoreći: 'Zašto si u njemu napisao da će doći kralj babilonski koji će opustošiti zemlju ovu i istrijebiti i ljude i stoku?'"},{"v":30,"t":"Zato ovako govori Jahve protiv Jojakima, kralja judejskoga: 'On neće imati potomka da sjedne na prijestolje Davidovo, a njegovo mrtvo tijelo bit će bačeno na pripeku danju i noćni mraz."},{"v":31,"t":"Kaznit ću njega, i potomstvo njegovo, i sluge njegove zbog njihova bezakonja, i svalit ću na Jeruzalemce i na Judejce sve zlo kojim sam im prijetio, a nisu me slušali.”"},{"v":32,"t":"Tada Jeremija uze drugi svitak, dade ga pisaru Baruhu, sinu Nerijinu, i on po kazivanju Jeremijinu upisa sve riječi knjige koju je Jojakim, kralj judejski, na žeravnici spalio. I k njima je dopisano još mnogo onakvih riječi."}]},"37":{"hr":[{"v":1,"t":"Nakon Konije, sina Jojakimova, zakralji se Sidkija, sin Jošijin. Nabukodonozor, kralj babilonski, postavi ga za kralja u zemlji judejskoj."},{"v":2,"t":"Ali ni on ni sluge njegove ni narod zemlje ne slušahu riječi što ih je Jahve govorio na usta proroka Jeremije."},{"v":3,"t":"Kralj Sidkija posla Jehukala, sina Šelemjina, i svećenika Sefaniju, sina Maasejina, k proroku Jeremiji s porukom: “Daj, pomoli se za nas Jahvi, Bogu našemu!”"},{"v":4,"t":"Jeremija u ono vrijeme još zalažaše među narod i još ga ne bijahu bacili u tamnicu."},{"v":5,"t":"A vojska je faraonova nadirala iz Egipta: čuvši to, Kaldejci, koji opsjedahu Jeruzalem, udaljiše se od grada."},{"v":6,"t":"Tada se javi riječ Jahvina proroku Jeremiji:"},{"v":7,"t":"Ovako govori Jahve, Bog Izraelov: “Kralju judejskomu, koji vas posla k meni da me pitate, ovako recite: 'Evo, vojska faraonova, koja vam priteče u pomoć, vratit će se u svoju zemlju Egipat."},{"v":8,"t":"Kaldejci će opet napasti ovaj grad, osvojiti ga i spaliti.'"},{"v":9,"t":"Ovako govori Jahve: 'Ne zanosite se mišlju: 'Kaldejci će otići od nas', jer oni neće otići!"},{"v":10,"t":"Pa i da razbijete svu vojsku kaldejsku koja se bori s vama, tako da bi od nje ostali samo ranjenici, oni bi, svaki iz svoga šatora, opet poustajali da požarom unište ovaj grad.'”"},{"v":11,"t":"Kad je vojska kaldejska zbog vojske faraonove morala prekinuti opsadu Jeruzalema,"},{"v":12,"t":"i Jeremija htjede otići iz Jeruzalema da ode u zemlju Benjaminovu te ondje od rođaka dobije dio."},{"v":13,"t":"Ali kad stiže do Benjaminovih vrata, ondje bijaše zapovjednik straže Jirijaj, sin Hananijina sina Šelemje. On zaustavi proroka Jeremiju povikavši: “Ti hoćeš prebjeći Kaldejcima!” Jeremija odgovori:"},{"v":14,"t":"“Nije istina, ne želim prebjeći Kaldejcima!” Ali i ne slušajući Jeremiju, Jirijaj ga uhvati i odvede dostojanstvenicima."},{"v":15,"t":"Dostojanstvenici se razljutiše na Jeremiju te ga istukoše i zatvoriše u kuću pisara Jonatana, koju bijahu pretvorili u tamnicu."},{"v":16,"t":"Tako Jeremija dospje u nadsvođen podrum. Ondje Jeremija ostade mnogo vremena."},{"v":17,"t":"Tada kralj Sidkija posla po njega. I nasamo, u dvoru, kralj ga upita: “Ima li riječi od Jahve?” A na to će Jeremija: “Dakako!” I dometne: “Bit ćeš predan u ruke kralja babilonskoga!”"},{"v":18,"t":"Onda Jeremija kaza kralju Sidkiji: “Što skrivih tebi, tvojim slugama i ovom narodu te me baciste u tamnicu?"},{"v":19,"t":"Gdje su sada vaši proroci koji vam prorekoše: 'Kralj babilonski neće udariti na vas ni na ovu zemlju?'"},{"v":20,"t":"A sada, hajde, čuj mene, gospodaru moj i kralju, usliši molbu moju! Nemoj da me opet vrgnu u kuću pisara Jonatana, da ondje ne umrem!”"},{"v":21,"t":"Tada kralj Sidkija naredi i Jeremiju odvedoše u tamničko dvorište te mu davahu svaki dan pogaču kruha iz Pekarske ulice, sve dok nije ponestalo kruha u gradu. I tako Jeremija ostade u tamničkom dvorištu."}]},"38":{"hr":[{"v":1,"t":"Šefatja, sin Matanov, i Gedalija, sin Pašhurov, i Jukal, sin Šelemjin, i Pašhur, sin Malkijin, čuše tada za riječi što ih Jeremija kaza svemu narodu:"},{"v":2,"t":"“Ovako govori Jahve: 'Tko ostane u ovome gradu, poginut će od mača, gladi i kuge. A tko izađe pred Kaldejce, spasit će život - život će mu ostati kao plijen, ostat će živ.'"},{"v":3,"t":"Jer ovako govori Jahve: 'Ovaj će grad odista pasti u ruke vojsci kralja babilonskoga i ona će ga zauzeti!'”"},{"v":4,"t":"Tada dostojanstvenici rekoše kralju: “Ovoga čovjeka valja ubiti: on zaista obeshrabruje ratnike koji su još ostali u gradu i sav narod kad takve riječi pred njima govori. Pa taj čovjek ne traži dobrobit ovoga naroda, nego njegovu propast.”"},{"v":5,"t":"A kralj Sidkija odgovori: “Eto, on je u vašim rukama, jer kralj ionako više nema nikakve vlasti nad vama.”"},{"v":6,"t":"Tada pograbiše Jeremiju i baciše ga u čatrnju kraljevića Malkije, što je bila u tamničkom dvorištu, i oni ga spustiše na užetima. Ali u čatrnji ne bijaše vode, već samo glib, tako da Jeremija propade u glib."},{"v":7,"t":"Ali Kušit Ebed-Melek, dvorjanin koji bijaše u kraljevskom dvoru, doču da su Jeremiju bacili u čatrnju dok je kralj upravo sjedio kod Benjaminovih vrata."},{"v":8,"t":"Tada Ebed-Melek izađe iz kraljevskog dvora te ovako reče kralju:"},{"v":9,"t":"“Gospodaru, kralju moj, zlo čine ovi ljudi kad tako postupaju s prorokom Jeremijom: bacili su ga u čatrnju, gdje će od gladi umrijeti, jer nema kruha u gradu.”"},{"v":10,"t":"Nato kralj zapovjedi Kušitu Ebed-Meleku: “Povedi trojicu ljudi te izvuci proroka Jeremiju iz čatrnje dok nije umro.”"},{"v":11,"t":"I Ebed-Melek povede ljude, uđe u kraljevski dvor, pod riznicu: uze ondje nešto iznošenih i poderanih dronjaka te ih na užetu spusti Jeremiji u čatrnju."},{"v":12,"t":"Kušit Ebed-Melek reče Jeremiji: “Podmetni iznošene i poderane dronjke pod pazuha i pod užad.” Jeremija učini tako."},{"v":13,"t":"Tada na užetima izvukoše Jeremiju iz čatrnje. Otada Jeremija ostade u tamničkom dvorištu."},{"v":14,"t":"Kralj Sidkija posla po proroka Jeremiju te ga pozva da dođe k njemu na treći ulaz što vodi u Dom Jahvin. Kralj reče Jeremiji: “Htio bih te nešto upitati, nemoj mi ni riječi zatajiti!”"},{"v":15,"t":"Jeremija odgovori Sidkiji: “Ako ti kažem, nećeš li me pogubiti? Ako te pak posvjetujem, nećeš me poslušati!”"},{"v":16,"t":"Tada se kralj Sidkija u tajnosti zakle Jeremiji ovim riječima: “Živoga mi Jahve, koji nam daje ovaj život, neću te pogubiti i neću te predati onima što ti rade o glavi.”"},{"v":17,"t":"Jeremija, dakle, reče Sidkiji: “Ovako govori Jahve, Bog nad Vojskama, Bog Izraelov: 'Ako izađeš pred vojskovođe kralja babilonskoga, spasit ćeš glavu i ovaj grad neće biti uništen požarom; živjet ćete ti i tvoj dom."},{"v":18,"t":"Ako pak ne izađeš pred vojskovođe kralja babilonskoga, ovaj će grad pasti u ruke Kaldejaca i oni će ga spaliti, a ti se nećeš spasiti iz ruku njihovih.'”"},{"v":19,"t":"A kralj Sidkija odgovori Jeremiji: “Bojim se Judejaca koji su prebjegli Kaldejcima: mogli bi mene predati njima da mi se izruguju.”"},{"v":20,"t":"Jeremija odvrati: “Oni to neće učiniti. Poslušaj glas Jahvin prema kojem sam ti govorio, bit će ti dobro i spasit ćeš život svoj."},{"v":21,"t":"Ali ako ne htjedneš iz grada, evo riječi koju mi Jahve objavi:"},{"v":22,"t":"'Gle, sve žene koje su još ostale u dvoru kralja judejskoga bit će odvedene k vojskovođama kralja babilonskoga i govorit će: Zaveli te, svladali te vjerni prijatelji tvoji! Kad ti noge u kal propadaju, oni te napuštaju!'"},{"v":23,"t":"Da, sve će žene tvoje i djecu tvoju odvesti Kaldejcima, a ni ti sam nećeš umaći rukama njihovim: dospjet ćeš u ruke kralju babilonskom, a grad će ovaj biti spaljen.”"},{"v":24,"t":"Sidkija reče Jeremiji: “Nitko živ ne smije o tome što saznati, inače ćeš umrijeti."},{"v":25,"t":"Ako, dakle, dostojanstvenici doznaju da sam s tobom razgovarao te dođu k tebi i kažu: 'TÓa očituj nam što kralj kaza tebi, a ti njemu; ne krij ništa pred nama, inače ćemo te ubiti',"},{"v":26,"t":"odgovori im: 'Molio sam kralja da me više ne vrati u kuću Jonatanovu, da ondje ne umrem!'”"},{"v":27,"t":"I doista, dođoše dostojanstvenici k Jeremiji te ga ispitivahu. Ali im on odgovori upravo onako kako mu kralj bijaše naredio. Tada ga se okaniše, jer se ništa nije pročulo o onom razgovoru."},{"v":28,"t":"Jeremiju, dakle, ostaviše u tamničkom dvorištu sve do dana kad neprijatelj zauze Jeruzalem. Kad Jeruzalem zauzeše, on bijaše ondje."}]},"39":{"hr":[{"v":1,"t":"Devete godine kralja Sidkije, kralja judejskoga, desetoga mjeseca, Nabukodonozor, kralj babilonski, krenu sa svom vojskom na Jeruzalem te ga opsjede."},{"v":2,"t":"Jedanaeste godine kralja Sidkije, četvrtoga mjeseca, dana devetoga u mjesecu, provališe u grad."},{"v":3,"t":"Uđoše sve vojskovođe kralja babilonskoga te se smjestiše kod Srednjih vrata: Nergal Sar-Eser, knez Sin-Magira, vrhovni zapovjednik, Nebušasban, visoki dostojanstvenik, i sve druge vojskovođe kralja babilonskoga."},{"v":4,"t":"Kad ih vidješe Sidkija, kralj judejski, i svi ratnici njegovi, dadoše se u bijeg na vrata između dva zida, noću iziđoše iz grada prema Kraljevu vrtu i krenuše k dolini Arabi."},{"v":5,"t":"Ali ih čete kaldejske gonjahu i sustigoše Sidkiju u Poljanama jerihonskim. Uhvatiše ga, odvedoše u Riblu, u zemlju hamatsku, pred Nabukodonozora, kralja babilonskoga, koji mu izreče sud."},{"v":6,"t":"I kralj babilonski dade u Ribli pred očima kralja Sidkije zaklati djecu njegovu. A dade kralj babilonski pogubiti i sve odličnike judejske."},{"v":7,"t":"Sidkiji iskopa oči, stavi ga u okove da ga odvede u Babilon."},{"v":8,"t":"Kaldejci zapališe kraljev dvor i kuće naroda i porušiše bedeme jeruzalemske."},{"v":9,"t":"Ostatak pučanstva koje još ostade u gradu, izbjeglice što su mu se predale i sav ostali narod, izagna u Babilon Nebuzaradan, zapovjednik tjelesne straže."},{"v":10,"t":"A od siromašnoga puka koji nije ništa posjedovao, Nebuzaradan, zapovjednik tjelesne straže, ostavi neke u zemlji judejskoj i porazdijeli im vinograde i polja."},{"v":11,"t":"O Jeremiji Nabukodonozor, kralj babilonski, zapovjedi Nebuzaradanu, zapovjedniku tjelesne straže:"},{"v":12,"t":"“Uzmi ga i oko tvoje neka bdi nad njim. Ne čini mu nikakva zla, nego postupaj s njime kako on bude želio.”"},{"v":13,"t":"Tada Nebuzaradan, zapovjednik tjelesne straže, Nebušazdan, visoki dostojanstvenik, Nergal Sar-Eser, vrhovni zapovjednik, i sve vojskovođe kralja babilonskoga"},{"v":14,"t":"poslaše ljude da izvedu Jeremiju iz tamničkoga dvorišta i pustiše ga na slobodu. I tako on osta među narodom."},{"v":15,"t":"Dok je Jeremija bio zatvoren u tamničkom dvorištu, dođe mu riječ Jahvina:"},{"v":16,"t":"“Idi i reci Kušitu Ebed-Meleku: Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Evo, učinit ću da se ispune moje riječi protiv ovoga grada, na nesreću, ne na spas njegov. I kad se u onaj dan na tvoje oči obistine,"},{"v":17,"t":"ja ću te u onaj dan spasiti - riječ je Jahvina - i nećeš biti predan u ruke ljudima pred kojima dršćeš,"},{"v":18,"t":"jer ja ću te pouzdano spasiti te nećeš od mača poginuti, nego ćeš dobiti život kao plijen, jer si se u me pouzdao' - riječ je Jahvina.”"}]},"40":{"hr":[{"v":1,"t":"Ovo je riječ koju Jahve uputi Jeremiji pošto ga Nebuzaradan, zapovjednik tjelesne straže, bijaše pustio iz Rame. Odvojio ga je kad je već, u lance okovan, bio među svim jeruzalemskim i judejskim izgnanicima koje vođahu u Babilon."},{"v":2,"t":"Odvojivši ga, dakle, zapovjednik tjelesne straže reče mu: “Jahve, Bog tvoj, zaprijetio je nesrećom ovome mjestu."},{"v":3,"t":"Izvršio je i učinio kako bijaše zaprijetio, jer ste griješili protiv Jahve i niste slušali glasa njegova. Zato vas je i snašlo ovo zlo."},{"v":4,"t":"Evo, sada driješim okove s ruku tvojih. Ako ti je po volji da ideš sa mnom u Babilon, pođi sa mnom i oko će moje bdjeti nad tobom. Ako ti nije volja ići sa mnom u Babilon, ti ostani. Gle, sva je zemlja pred tobom: možeš ići kamo ti oko želi i gdje će ti biti dobro."},{"v":5,"t":"Ako, dakle, hoćeš ostati, možeš poći Gedaliji, sinu Šafanova sina Ahikama, koga je kralj babilonski postavio nad gradovima judejskim, i ostati kod njega usred naroda, ili pak možeš ići kamo ti drago.” Zatim mu zapovjednik tjelesne straže dade hrane i k tomu dar te ga otpusti."},{"v":6,"t":"Tada se Jeremija otputi u Mispu, Gedaliji, sinu Ahikamovu, te osta kod njega među narodom koji je ostao u zemlji."},{"v":7,"t":"Svi vojni zapovjednici i njihovi ljudi uokolo saznaše da je kralj babilonski postavio zemlji za namjesnika Ahikamova sina Gedaliju te mu povjerio muževe, žene i djecu i siromahe koji još ne bijahu odvedeni u babilonsko sužanjstvo."},{"v":8,"t":"I dođoše pred Gedaliju u Mispu: Netanijin sin Jišmael, Kareahov sin Johanan; Tanhumetov sin Seraja, Zatim sinovi Efaja Netofljanina, Makatijev sin Jaazanija - oni i njihovi ljudi."},{"v":9,"t":"Gedalija, sin Šafanova sina Ahikama, zakle se njima i njihovim ljudima i reče: “Ne bojte se služiti Kaldejcima, ostanite u zemlji, budite odani babilonskom kralju i bit će vam dobro."},{"v":10,"t":"A ja ću, evo, ostati u Mispi na službu Kaldejcima koji dolaze k nama. Vi pak potrgajte grožđe, poberite voće i masline, pohranite u sudove i ostanite u gradovima što ih zaposjedoste.”"},{"v":11,"t":"I svi Judejci što se zatekoše u Moabu, kod sinova Amonovih, i u Edomu, po svim zemljama, saznadoše da je kralj babilonski ostavio ostatak u Judeji i da je postavio nad njim Gedaliju, sina Šafanova sina Ahikama."},{"v":12,"t":"I onda se vratiše svi Judejci iz svih mjesta kamo ih bijahu raspršili, vratiše se u zemlju judejsku Gedaliji u Mispu te nabraše veoma mnogo grožđa i drugoga voća."},{"v":13,"t":"A Johanan, sin Kareahov, i svi vojni zapovjednici pođoše Gedaliji u Mispu"},{"v":14,"t":"te mu rekoše: “A znaš li ti da je amonski kralj Baalis poslao Jišmaela, sina Netanijina, da te ubije?” Ali im Gedalija, sin Ahikamov, ne povjerova."},{"v":15,"t":"Tada reče Johanan, sin Kareahov, potajno Gedaliji u Mispi: “Idem da ubijem Jišmaela, sina Netanijina, tako da nitko neće doznati. Zašto da on tebe ubije i da se opet rasprše svi Judejci što se oko tebe skupiše? I zašto da propadne ostatak Judejaca?”"},{"v":16,"t":"Ali Gedalija, sin Ahikamov, uzvrati Johananu, sinu Kareahovu: “Nemoj toga raditi! Jer je laž što govoriš o Jišmaelu.”"}]},"41":{"hr":[{"v":1,"t":"Ali u sedmom mjesecu dođe Jišmael, sin Elišamina sina Netanije, roda kraljevskoga, sa deset ljudi i potraži Gedaliju, sina Ahikamova, u Mispi. I dok su se ondje, u Mispi, zajedno gostili,"},{"v":2,"t":"diže se Jišmael, sin Netanijin, sa svojom desetoricom i mačem smakoše Gedaliju, sina Ahikamova. I tako ubi čovjeka koga kralj babilonski bijaše postavio nad zemljom."},{"v":3,"t":"A i sve Judejce koji bijahu s njim u Mispi, i Kaldejce, vojnike što se tu nađoše - Jišmael dade pogubiti."},{"v":4,"t":"Sutradan, pošto Gedalija bi ubijen, dok još nitko nije znao što se zbilo,"},{"v":5,"t":"dođoše ljudi iz Šekema, Šila i Samarije, njih osamdeset, obrijane brade, poderanih haljina i s urezima po tijelu, noseći u rukama prinose i tamjan da ih prinesu u Domu Jahvinu."},{"v":6,"t":"Jišmael, sin Netanijin, iziđe im iz Mispe u susret, dok su oni, plačući, išli svojim putem. Kad ih stiže, reče im: “Dođite Gedaliji, sinu Ahikamovu!”"},{"v":7,"t":"A kad stigoše usred grada, Jišmael, sin Netanijin, i njegovi ljudi poklaše ih i baciše u čatrnju."},{"v":8,"t":"A među njima bijaše deset ljudi koji rekoše Jišmaelu: “Nemoj nas ubiti, jer imamo u poljima zakopanih zaliha pšenice, ječma, ulja i meda.” On tada odusta i ne ubi ih s braćom njihovom."},{"v":9,"t":"A čatrnja u koju je Jišmael pobacao sva tjelesa pobijenih ljudi, velika čatrnja, bijaše ona ista koju je kralj Asa načinio protiv Baše, kralja izraelskoga. I sad ju je Jišmael, sin Netanijin, napunio pobijenim ljudima."},{"v":10,"t":"Tada Jišmael odvede ostatak naroda iz Mispe, zajedno s kćerima kraljevim koje je Nebuzaradan, zapovjednik tjelesne straže, povjerio Gedaliji, sinu Ahikamovu: u cik zore krenu Jišmael, sin Netanijin, i zaputi se da prijeđe u zemlju Amonovih sinova."},{"v":11,"t":"Ali kad Johanan, sin Kareahov, i svi vojni zapovjednici koji bijahu s njim saznadoše za sva zlodjela što ih Jišmael, sin Netanijin, bijaše počinio,"},{"v":12,"t":"uzeše sve svoje vojnike te krenuše u boj na Jišmaela, sina Netanijina. Nađoše ga uz veliku vodu u Gibeonu."},{"v":13,"t":"Čim oni ljudi što bijahu kod Jišmaela ugledaše Johanana, sina Kareahova, i sve vojne zapovjednike koji bijahu s njime, obradovaše se,"},{"v":14,"t":"i sav narod što ga je Jišmael odveo iz Mispe okrenu se i potrča Johananu, sinu Kareahovu."},{"v":15,"t":"Ali Jišmael, sin Netanijin, sa osam ljudi, pobježe od Johanana i ode k sinovima Amonovim."},{"v":16,"t":"Tada Johanan, sin Kareahov, i svi vojni zapovjednici koji bijahu s njim uzeše sav preostali narod što ga Jišmael, sin Netanijin, pošto ubi Gedaliju, sina Ahikamova, bijaše doveo iz Mispe: muškarce, žene i djecu i dvorjane koje dovede iz Gibeona."},{"v":17,"t":"Krenuše, a kod Svratišta Kimhama, koje je kraj Betlehema, oni se odmarahu da bi mogli nastaviti put i stići u Egipat,"},{"v":18,"t":"što dalje od Kaldejaca, kojih se bojahu: jer je Jišmael, sin Netanijin, ubio Gedaliju, sina Ahikamova, koga kralj babilonski bijaše postavio za namjesnika u zemlji."}]},"42":{"hr":[{"v":1,"t":"Nato svi vojni zapovjednici, osobito Johanan, sin Kareahov, i Azarja, sin Hošajin, i sav narod, malo i veliko, pristupiše"},{"v":2,"t":"i rekoše proroku Jeremiji: “Pomno počuj molbu našu! Zagovaraj nas pred Jahvom, Bogom svojim, za sav ovaj ostatak, jer nas, kako i sam vidiš, ostade još samo malo od velikoga broja koliko nas je nekoć bilo."},{"v":3,"t":"Neka nam Jahve, Bog tvoj, objavi kuda da krenemo i što valja da činimo.”"},{"v":4,"t":"Prorok im Jeremija odgovori: “Pristajem. Pomolit ću se, kao što rekoste, Jahvi, Bogu vašemu, i javit ću vam sve što on odgovori, ni riječi vam neću zatajiti.”"},{"v":5,"t":"Oni pak rekoše Jeremiji: “Neka Jahve bude istinit i vjerodostojan svjedok protiv nas ako ne postupimo sasvim po riječima koje će nam Jahve, Bog tvoj, po tebi objaviti."},{"v":6,"t":"Bio povoljan ili nepovoljan glas Jahve, Boga našega, komu te šaljemo, mi ćemo ga slušati da nam dobro bude što poslušasmo glas Jahve, Boga svojega.”"},{"v":7,"t":"Poslije deset dana dođe riječ Jahvina Jeremiji."},{"v":8,"t":"Tada on pozva Johanana, sina Kareahova, sve vojne zapovjednike koji bijahu s njim i sav narod, malo i veliko,"},{"v":9,"t":"te im reče: “Ovako govori Jahve, Bog Izraelov, kojemu ste me poslali da izlijem preda nj molbu vašu:"},{"v":10,"t":"'Ako budete mirno živjeli u zemlji ovoj, podići ću vas i neću vas više razoriti; posadit ću vas, a ne iskorijeniti. Jer se kajem za zlo koje sam vam nanio."},{"v":11,"t":"Ne bojte se kralja babilonskoga od koga strahujete. Ne bojte ga se - riječ je Jahvina - jer ja sam s vama da vas spasim i izbavim iz ruku njegovih."},{"v":12,"t":"I ja ću vam pribaviti milost da vam se smiluje i pusti vas da u zemlji svojoj živite.'"},{"v":13,"t":"Ako pak kažete: 'Nećemo ostati u ovoj zemlji', ne pokoravajući se glasu Jahve, Boga svoga,"},{"v":14,"t":"ako kažete: 'Ne, u Egipat idemo, rata više da ne vidimo, glasa bojnog roga više da ne čujemo, da ne moramo biti više gladni kruha; da, onamo idemo',"},{"v":15,"t":"onda čujte riječ Jahvinu, vi koji ste Ostatak Judeje: Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Ako ste odlučili krenuti u Egipat da ondje živite,"},{"v":16,"t":"mač kojega se plašite u zemlji će vas egipatskoj dostići; glad od koje strahujete, u Egiptu će vam biti za petama: i ondje ćete umrijeti!"},{"v":17,"t":"I svi oni koji odluče da odu u Egipat i da se ondje nasele, poginut će od mača, gladi i kuge: nitko živ neće umaći nesreći koju ću na njih svaliti.'"},{"v":18,"t":"Jer ovako govori Jahve nad Vojskama, Bog Izraelov: 'Kao što se srdžba moja i bijes moj oboriše na Jeruzalemce, tako će se gnjev moj izliti i na vas ako pođete u Egipat: postat ćete prokletstvo, užas, kletva i poruga, a ovoga mjesta nikad više nećete ugledati.'"},{"v":19,"t":"Vama, koji ste Ostatak Judeje, Jahve poručuje da ne idete u Egipat. Dobro znajte da sam danas bio svjedok protiv vas."},{"v":20,"t":"Jer sami sebe obmanjujete. TÓa vi ste me poslali k Jahvi, Bogu svome rekavši: 'Zagovaraj nas pred Jahvom, Bogom našim, i saopći nam sve što ti on objavi, i mi ćemo to učiniti.'"},{"v":21,"t":"A danas sam vam objavio, ali vi ne slušate više glasa Jahve, Boga svojega, koji me k vama posla."},{"v":22,"t":"Znajte, dakle, dobro: od mača, gladi i kuge poginut ćete na mjestu kamo hoćete da odete da se ondje naselite.”"}]},"43":{"hr":[{"v":1,"t":"Kad je Jeremija svemu narodu kazao sve riječi Jahve, Boga njihova, sve one riječi radi kojih ga je Jahve, Bog njihov, k njima poslao,"},{"v":2,"t":"Azarja, sin Hošajin, i Johanan, sin Kareahov, i svi oni drski ljudi odgovoriše Jeremiji: “Laži nam govoriš. Nije te poslao Jahve da nam govoriš: 'Ne idite u Egipat da se ondje nastanite',"},{"v":3,"t":"nego Baruh, sin Nerijin, podgovori te da nas predaš u ruke Kaldejcima koji će nas pogubiti ili odvesti u sužanjstvo babilonsko!”"},{"v":4,"t":"I Johanan, sin Kareahov, i svi zapovjednici i sav narod ne poslušaše glasa Jahvina da ostanu u zemlji judejskoj."},{"v":5,"t":"Nego Johanan, sin Kareahov, i vojni zapovjednici povedoše sav ostatak Judin, one što se vratiše iz zemalja kamo bijahu izagnani, da se nastane u zemlji judejskoj:"},{"v":6,"t":"muževe, žene i djecu i sve kraljevske kćeri i sve ljude koje je Nebuzaradan, zapovjednik tjelesne straže, ostavio kod Gedalije, sina Šafanova sina Ahikama, pa i proroka Jeremiju, i Baruha, sina Nerijina,"},{"v":7,"t":"te se oni iseliše u Egipat, jer ne slušahu glasa Jahvina. I tako dođoše u Tafnis."},{"v":8,"t":"U Tafnisu dođe riječ Jahvina Jeremiji:"},{"v":9,"t":"“Uzmi u ruke velikoga kamenja i ugradi ga, pred svim Judejcima, meljtom u pločnik što je pred ulazom u faraonov dvor."},{"v":10,"t":"I reci im: Ovako govori Jahve nad Vojskama, kralj Izraelov: 'Evo šaljem po slugu svojega Nabukodonozora, kralja babilonskoga. On će postaviti prijestolje na ovo kamenje što sam ga ugradio i nad njim će razapeti svoju nebnicu."},{"v":11,"t":"Da, doći će i udarit će na zemlju egipatsku: Tko je za smrt, u smrt! Tko za izgnanstvo, u izgnanstvo! Tko za mač, pod mač!"},{"v":12,"t":"On će vatrom sažeći hramove bogova egipatskih, spalit će i izagnati bogove, očistit će zemlju egipatsku kao što pastir svoj plašt otrijebi od buha. I onda će, nesmetan, odavde otići."},{"v":13,"t":"Porazbijat će spomenike hrama Sunca koji je u Heliopolu, a hramove bogova egipatskih ognjem će spaliti.'”"}]},"44":{"hr":[{"v":1,"t":"Riječ koja se javi Jeremiji za sve Judejce što življahu u zemlji egipatskoj, što življahu u Migdolu, u Tafnisu, u Memfisu i u zemlji Patrosu."},{"v":2,"t":"Ovako govori Jahve nad Vojskama, Bog Izraelov: “I sami vidjeste svu nesreću koju sam svalio na Jeruzalem i na sve gradove judejske: evo danas su to gomile ruševina, a u njima nitko više ne živi,"},{"v":3,"t":"zbog nedjela njihovih što ih učiniše da bi mene vrijeđali, polazeći drugim bogovima kojih nisu poznavali ni oni, ni vi, ni oci vaši, da im kade i da im služe."},{"v":4,"t":"A ja sam vam jednako slao svoje sluge proroke da vam kažu: 'Ne činite tih gnusoba koje su mi ogavne!'"},{"v":5,"t":"Ali me oni nisu slušali, niti su uho svoje priklonili da se okane zloće svoje i prestanu kaditi tuđim bogovima."},{"v":6,"t":"Zato se izli gnjev moj i srdžba moja i rasplamtje se u gradovima judejskim i po ulicama jeruzalemskim, te se pretvoriše u pustoš i razvaline, kao što su danas."},{"v":7,"t":"Zašto sami svaljujete na se tako golemu nesreću” - govori Jahve, Bog nad Vojskama, Bog Izraelov - “te sami do korijena istrebljujete iz Judeje sve muško i žensko, djecu i dojenčad, te vam ni ostatka ostati neće,"},{"v":8,"t":"jer me vrijeđate djelima ruku svojih, kadeći tuđim bogovima u zemlji egipatskoj, u koju ste došli prebivati, a bit ćete iskorijenjeni i postat ćete kletva i ruglo među svim narodima na zemlji?"},{"v":9,"t":"Jeste li zaboravili bezakonja otaca svojih, bezakonja kraljeva judejskih, bezakonja knezova svojih i žena njihovih i bezakonja svoja, bezakonja žena svojih, počinjena u zemlji judejskoj i po ulicama jeruzalemskim?"},{"v":10,"t":"Do dana današnjega nisu se pokajali, nisu se bojali, nisu živjeli po Zakonu mojemu ni po odredbama mojim, koje dadoh vama i ocima vašim.”"},{"v":11,"t":"Zato ovako govori Jahve nad Vojskama, Bog Izraelov: “Evo, okrećem svoje lice vama, na nesreću vašu, da zatrem svu zemlju judejsku."},{"v":12,"t":"Odnijet ću ostatak Judeje koji je odlučio da ide u zemlju egipatsku da se ondje stani; svi će izginuti u zemlji egipatskoj, past će od mača, od gladi će pogibati, poginut će svi, malo i veliko, pomrijet će od mača i gladi, i bit će prokletstvo, užas, kletva i poruga."},{"v":13,"t":"Kaznit ću sve koji budu u zemlji egipatskoj, kao što sam kaznio Jeruzalem: mačem, glađu i kugom."},{"v":14,"t":"A od ostatka Judeje koji je došao da se stani u Egiptu, nitko neće uteći ni preživjeti da bi se mogao vratiti u zemlju judejsku za kojom im duše čeznu, da se u nju vrate i ondje nastane. Jer se nitko neće vratiti, osim izbjeglica.”"},{"v":15,"t":"I tada svi muškarci koji su znali da im žene kade tuđim bogovima, i sve nazočne žene, u velikom mnoštvu, i sav narod što življaše u zemlji egipatskoj i u Patrosu odgovoriše Jeremiji:"},{"v":16,"t":"“Riječi koje si u ime Jahvino nama objavio mi ne slušamo;"},{"v":17,"t":"naprotiv, i dalje ćemo se držati zadane riječi: kadit ćemo nebeskoj kraljici i lijevati ljevanice, kao što smo i mi i oci naši, naši kraljevi i knezovi činili u gradovima judejskim i po ulicama jeruzalemskim: tada imadosmo kruha izobila, bijasmo sretni i ne trpjesmo nikakvih nesreća."},{"v":18,"t":"Ali otkako prestadosmo kaditi nebeskoj kraljici i lijevati joj ljevanice, u svemu smo oskudijevali i od mača i gladi pogibali.”"},{"v":19,"t":"A žene rekoše: “Kad kadimo kraljici nebeskoj i lijevamo joj ljevanice, zar joj bez znanja svojih muževa pečemo kolače u obliku lika njezina i lijevamo ljevanice?”"},{"v":20,"t":"Tada Jeremija svemu narodu, muškarcima i ženama, i svim ljudima koji su mu tako govorili reče:"},{"v":21,"t":"“Nije li se Jahve spomenuo i nije li ga u srce dirnuo tamjan što ste ga palili po ulicama jeruzalemskim, vi i oci vaši, vaši kraljevi, knezovi i puk zemaljski?"},{"v":22,"t":"Jahve više nije mogao podnositi zlodjela vaših i gnusoba koje počiniste, i zato se zemlja vaša pretvorila u pustoš i ruševine, u prokletstvo, bez stanovnika, kao što je i danas."},{"v":23,"t":"Zbog toga što ste, prinoseći tamjan, zgriješili Jahvi, što Jahvina glasa ne slušaste i Jahvina se Zakona i njegovih se naredaba i svjedočanstava ne držaste, snađe vas ova nevolja, kakva je danas.”"},{"v":24,"t":"Zatim reče Jeremija svemu narodu, osobito ženama: “Čujte riječ Jahvinu, svi Judejci koji ste u zemlji egipatskoj:"},{"v":25,"t":"Ovako govori Jahve nad Vojskama, Bog Izraelov: 'Vi žene, ono što vaša usta obećaju, to vaše ruke moraju i izvršiti. Rekoste: 'Mi ćemo se tvrdo držati zavjeta što ih učinismo: kaditi kraljici nebeskoj i lijevati joj ljevanice.' Držite se samo svojih zavjeta i lijevajte revno ljevanice!"},{"v":26,"t":"Ali čujte zato riječ Jahvinu, svi vi Judejci nastanjeni u zemlji egipatskoj! Evo, zaklinjem se velikim imenom svojim,' govori Jahve. 'U svoj zemlji egipatskoj nijedna usta judejska neće više izustiti mojega imena; nitko neće reći: 'Živoga mi Jahve!'"},{"v":27,"t":"Evo, bdim nad njima, na nesreću, a ne na dobro njihovo: svi ljudi judejski što su u zemlji egipatskoj poginut će od mača i gladi do potpunog istrebljenja."},{"v":28,"t":"I bit će malo onih koji će izbjeći maču i vratiti se iz egipatske zemlje u zemlju judejsku. Onda će sav ostatak judejski, svi koji dođoše u zemlju egipatsku da ondje žive, spoznati čija riječ vrijedi, moja ili njihova."},{"v":29,"t":"A ovo neka vam bude znamenje - riječ je Jahvina - da ću vas kazniti na ovome mjestu, da biste znali da će se vama na nesreću ispuniti prijetnje moje protiv vas.'"},{"v":30,"t":"Ovako govori Jahve: 'Gle, predat ću faraona Hofru, kralja egipatskoga, u ruke njegovim neprijateljima i u ruke onih koji mu rade o glavi, baš kao što sam Sidkiju, kralja Judejskoga, predao u ruke Nabukodonozora, kralja babilonskoga, neprijatelja njegova, koji mu je radio o glavi.'”"}]},"45":{"hr":[{"v":1,"t":"Riječ koju uputi Jeremija proroku Baruhu, sinu Nerijinu, dok je on te riječi iz usta Jeremijinih pisao u knjigu, četvrte godine Jojakima, sina Jošijina, kralja judejskoga:"},{"v":2,"t":"Ovako govori Jahve, Bog Izraelov, za tebe, Baruše:"},{"v":3,"t":"“Jer si rekao: 'Jao meni jer mi Jahve dodaje nevolju na nevolju. Sustadoh uzdišući i ne mogu naći mira!'"},{"v":4,"t":"Ovako govori Jahve: 'Evo, što sam sagradio, porušit ću, što sam zasadio, iščupat ću - po svoj zemlji!"},{"v":5,"t":"A ti tražiš za se čudesa! Ne traži toga! Jer, gle, svalit ću zlo na sve živo - riječ je Jahvina. A tebi ću kao plijen pokloniti život tvoj na svim mjestima kamo dođeš.'”"}]},"46":{"hr":[{"v":1,"t":"Riječ koju Jahve uputi proroku Jeremiji protiv naroda."},{"v":2,"t":"Još o Egiptu. Protiv vojske faraona Neka, kralja egipatskoga, što bijaše kod rijeke Eufrata, u Karkemišu, i kralj Nabukodonozor ga potuče, četvrte godine Jojakima, sina Jošijina, kralja judejskoga."},{"v":3,"t":"Pripremite štitove i oklope! Naprijed, u boj!"},{"v":4,"t":"Upregnite konje! Na kola, vozači! Postavite se pod kacigama! Naperite koplja! Navucite oklope!"},{"v":5,"t":"Što vidim? Zaprepašteni, uzmiču? Junaci njihovi, poraženi, u bijeg udariše glavom bez obzira! Užas odasvud - riječ je Jahvina."},{"v":6,"t":"Ni najbrži ne umače, ni najhrabriji ne uteče! Na sjeveru, na obali Eufrata, posrću i padaju."},{"v":7,"t":"Tko se to diže poput Nila, čije vode šume, k'o brzaci nabujaše?"},{"v":8,"t":"To Egipat se diže poput Nila, k'o brzaci vode mu nabujaše. I govori: dići ću se, poplaviti zemlju, opustošiti gradove i pučanstvo!"},{"v":9,"t":"Konji, naprijed! Poletite, kola bojna! Navalite, ratnici! Kušiti, Putijci, štitom zaštićeni, i Ludijci, što lukom strijeljate!"},{"v":10,"t":"Ovo je dan Jahve nad Vojskama - dan osvete da se dušmanima svojim osveti: mač će se nažderati, nasititi, glad utoliti krvlju njihovom! Jer Gospod, Jahve nad Vojskama, ima žrtveno klanje u sjevernoj zemlji uz obalu Eufrata."},{"v":11,"t":"Popni se na Gilead, balzama potraži, djevice, kćeri egipatska! Uzalud lijekovi mnogi: nema tebi ozdravljenja!"},{"v":12,"t":"Narodi čuše za tvoju sramotu, vapaji tvoji napuniše zemlju. Jer se junak o junaka spotiče i obojica padaju."},{"v":13,"t":"Riječ koju Jahve uputi proroku Jeremiji kad Nabukodonozor, kralj babilonski, dođe da udari na zemlju egipatsku."},{"v":14,"t":"Navijestite Egiptu, objavite u Migdolu, obznanite u Memfisu: “Svrstaj se! Spremi se! Jer mač već ždere sve oko tebe!"},{"v":15,"t":"Što? Zar Apis pobježe? Tvoj se Bik ne odrva?” Da, Jahve ga obori!"},{"v":16,"t":"On učini te mnogi posrnuše, popadaše jedan na drugoga. I gle, govore: “Na noge! Vratimo se svom narodu, rodnoj grudi svojoj, pred mačem koljačkim!”"},{"v":17,"t":"Faraonu, kralju egipatskom, ime nadjenite: “Graja što pravi čas promaši.”"},{"v":18,"t":"“Tako, života mi moga” - govori Kralj, komu je ime Jahve nad Vojskama - “ono će doći kao Tabor posred gora, kao Karmel iznad mora."},{"v":19,"t":"Spremi izgnanički zavežljaj, udomljena kćeri egipatska, jer Memfis će biti u pustoš pretvoren, poharan i nenastanjen."},{"v":20,"t":"Egipat bijaše lijepa junica, ali ide, ide na nju obad sa Sjevera."},{"v":21,"t":"A i plaćenici egipatski što k'o gojna telad usred nje življahu, i oni se okrenuše, u bijeg udariše, ne mogu se odhrvati jer ih stiže Dan propasti, dođe vrijeme da se kazne."},{"v":22,"t":"Slušaj! K'o da zmija sikće, sa svom silom dolaze, sjekirama na nju navaljuju, baš k'o drvosječe."},{"v":23,"t":"Posjeći će šumu - riječ je Jahvina - iako je neprohodna. Više ih je nego skakavaca, broja njima nema."},{"v":24,"t":"Osramoćena je zemlja egipatska, predana je narodu Sjevera.”"},{"v":25,"t":"Govori Jahve nad Vojskama, kralj Izraelov: “Evo, kaznit ću Amona Tebskoga, faraona i Egipat, i sve njegove bogove, kraljeve, faraona i sve koji se u nj uzdaju."},{"v":26,"t":"Predat ću ih u ruke onima što im rade o glavi, u ruke Nabukodonozora, kralja babilonskoga, i u ruke slugu njegovih. A poslije će Egipat biti opet naseljen, kao u stara vremena” - riječ je Jahvina."},{"v":27,"t":"“Ne boj se, Jakove, slugo moja, ne plaši se, Izraele! Jer, evo, spasit ću te izdaleka i potomstvo tvoje iz zemlje izgnanstva. Jakov će se opet smiriti, spokojno će živjet' i nitko ga neće plašiti."},{"v":28,"t":"Ne boj se, Jakove, slugo moja - riječ je Jahvina - jer ja sam s tobom. Zatrt ću narode među koje te prognah, a tebe neću sasvim uništiti: ali ću te kaznit' po pravici, ne smijem te pustit' nekažnjena.”"}]},"47":{"hr":[{"v":1,"t":"Riječ koju Jahve uputi proroku Jeremiji o Filistejcima prije nego što faraon osvoji Gazu."},{"v":2,"t":"Ovako reče Jahve: “Evo, vode se dižu sa Sjevera i kao nabujali brzaci poplavljuju zemlju i sve što je na njoj, gradove i sve njihovo pučanstvo. I ljudi vapiju, i kukaju svi žitelji zemlje,"},{"v":3,"t":"uz tutanj kopita njegove ždrebadi, uza štropot kola i tresku točkova. Oci više ne mare za djecu svoju jer su im ruke klonule"},{"v":4,"t":"zbog dana što osvanu da Filistejce istrijebi, da zatre Tiru i Sidonu sve do posljednjeg pomagača. Jer Jahve istrebljuje Filistejce, i sav ostatak otočja kaftorskog."},{"v":5,"t":"Gazi će biti obrijana glava, razoren Aškelon. A ti, Ašdode, ostače Anakovaca, dokle će te tuga razdirati?"},{"v":6,"t":"Jao, maču Jahvin, kad li ćeš se smiriti? Vrati se u korice, stani i počini!”"},{"v":7,"t":"Ali kako da se smiri, kad Jahvina ruka njime zapovijeda: na Aškelon i na morski žal on ga isuka."}]},"48":{"hr":[{"v":1,"t":"O Moabu. Ovako govori Jahve nad Vojskama, Bog Izraelov: “Jao brdu Nebu jer je opustošeno, postiđen je Kirjatajim i osvojen, tvrđa posramljena, razorena,"},{"v":2,"t":"nema više dike moapske. U Hešbonu mu propast skovaše: 'Hajde da ga istrijebimo iz naroda!' A ti, Madmene, bit ćeš razoren, mač već ide za tobom!"},{"v":3,"t":"Slušaj! Jauci se čuju iz Horonajima: 'Pohara, propast strašna!'"},{"v":4,"t":"'Moab je smlavljen!' čuje se vrištanje mališa njegovih."},{"v":5,"t":"Da, uz brdo Luhit uspinju se plačući. Da, niz obronke Horonajima razliježe se jauk nad propašću."},{"v":6,"t":"'Bježite, spasavajte život, ugledajte se u pustinjsku magarad!'"},{"v":7,"t":"Jer si se pouzdao u svoje utvrde, bit ćeš i ti osvojen. Kemoš odlazi u izgnanstvo sa svećenicima i knezovima svojim."},{"v":8,"t":"Pustošnik će doći u svaki grad, nijedan mu neće izmaći: Dolina će biti poharana, Visoravan opustošena,” govori Jahve!"},{"v":9,"t":"Stavite Moabu nadgrobni kamen, jer je do temelja srušen; njegovi su gradovi pustare, u njima nitko ne obitava."},{"v":10,"t":"Proklet bio tko nemarno obavlja poslove Jahvine! Proklet bio tko krvlju mač svoj ne omasti!"},{"v":11,"t":"Od mladosti svoje mir uživaše Moab, ležaše na droždini svojoj, nikad ga nisu pretakali iz bačve u bačvu, nikad u izgnanstvo išao nije: zato mu okus ostade svjež, miris nepromijenjen."},{"v":12,"t":"“Ali, evo, dolaze dani” - govori Jahve - “i ja ću mu poslati tlačitelje koji će ga pretakati, isprazniti njegove bačve i sudove njegove porazbijati."},{"v":13,"t":"I tada će se Moab postidjeti zbog Kemoša, kao što se dom Izraelov postidio zbog Betela u koji se uzdao.”"},{"v":14,"t":"Kako možete reći: “Mi smo junaci, hrabri ratnici.”"},{"v":15,"t":"Pustošnik Moabov navaljuje na nj; cvijet mladosti njegove u klanice silazi, riječ je Kraljeva, Jahve nad Vojskama njemu je ime."},{"v":16,"t":"Bliži se propast Moabova, nesreća njegova hiti."},{"v":17,"t":"Žalite ga, svi susjedi njegovi, i svi koji znate ime njegovo. Recite: “Kako li se slomi čvrsta palica, žezlo veličanstveno!”"},{"v":18,"t":"Siđi sa slave svoje, sjedni u blato, žitelju, kćeri dibonska! Jer pustošnik Moaba navali na te, poruši sve utvrde tvoje."},{"v":19,"t":"Stani na cestu i promatraj, o žitelju Aroera! Pitaj bjegunce i preživjele, pitaj ih: “Što se to dogodi?”"},{"v":20,"t":"“Moab se stidi jer je slomljen. Plačite, jecajte! Objavite na Arnonu da je Moab poharan.”"},{"v":21,"t":"Sud stiže nad Visoravan i nad Holon, Jahsu i Mefaot,"},{"v":22,"t":"nad Dibon, Nebo, Bet Diblatajim,"},{"v":23,"t":"Kirjatajim, Bet Gamul, Bet Meon,"},{"v":24,"t":"Kerijot, Bosru i nad sve gradove zemlje moapske, daleke i blize."},{"v":25,"t":"“Moabu je rog odbijen, ruka mu je slomljena.”"},{"v":26,"t":"“Opijte ga jer se htjede uzvisiti nad Jahvu: neka se Moab sada valja u bljuvotini svojoj te i on neka bude na podsmijeh."},{"v":27,"t":"Nije li tebi bio Izrael na podsmijeh? Jesu li ga možda zatekli u krađi te mašeš glavom kad god o njemu govoriš?”"},{"v":28,"t":"“Ostavite gradove, živite u pećinama, stanovnici Moaba! Budite kao golubovi što se gnijezde na litici onkraj razjapljena bezdana!”"},{"v":29,"t":"Čuli smo za nadutost Moaba, nadutost preveliku, ponos njegov, hvastanje, uznositost, za oholost srca njegova!"},{"v":30,"t":"“Poznajem ja obijest njegovu - riječ je Jahvina - laž njegovih riječi, laž djela njegovih!"},{"v":31,"t":"Zato moram jaukati nad Moabom, plakati nad svim Moapcima, jecati zbog ljudi Kir Heresa."},{"v":32,"t":"Više nego nad Jazerom, plakat ću nad tobom, o lozje sibmansko, kojem se mladice pružahu preko mora, sezahu sve do Jazera. Na tvoje berbe i žetve pade sada pustošnik."},{"v":33,"t":"Iščeznu radost i veselje iz voćnjaka i zemlje moapske. Nesta vina u kacama, mastioci više grožđa ne maste, veseli zvuci više nisu veseli.”"},{"v":34,"t":"Urlanje Hešbona i Elalea čuje se sve do Jahasa. Viču od Soara do Horonajima i Eglat Šelišije, jer se i vode nimrimske pretvoriše u pustaru."},{"v":35,"t":"“U Moabu ću učiniti - riječ je Jahvina - da se ne uzlazi na uzvišice i kadi bogovima njegovim."},{"v":36,"t":"Stoga mi srce poput frule dršće za Moabom, srce moje poput frule dršće za ljudima Kir Heresa: jer propade stečevina koju stekoše!"},{"v":37,"t":"Sve su glave obrijane i brade podrezane; po svim rukama urezi, oko bokova kostrijet."},{"v":38,"t":"Na svim krovovima Moaba i na njegovim trgovima samo zapomaganje, jer smrskah Moab kao krčag koji se nikomu ne mili” - riječ je Jahvina."},{"v":39,"t":"Kako li je smrskan! Kako li sramotno Moab udari u bijeg! Moab postade ruglo i strašilo svim susjedima."},{"v":40,"t":"Jer ovako govori Jahve: “Gle, poput orla lebdi, nad Moabom širi krila."},{"v":41,"t":"Gradovi su zauzeti, osvojene tvrđave. Srce moapskih junaka bit će toga dana kao srce žene u trudovima."},{"v":42,"t":"Izbrisan je Moab iz naroda jer se uzvisi nad Jahvu."},{"v":43,"t":"Strava, jama i zamka tebi, žitelju Moaba! - riječ je Jahvina."},{"v":44,"t":"Tko stravi umakne, u jamu će pasti; tko se iz jame izvuče, u zemlju će pasti. Da, to ću svaliti na Moab u danima kazne njegove” - riječ je Jahvina."},{"v":45,"t":"“U sjeni se hešbonskoj ustavljaju iscrpljeni bjegunci. Al' vatra izlazi iz Hešbona, plamen liže iz dvora sihonskog i proždire sljepoočnice Moabu i tjeme sinova nemirničkih."},{"v":46,"t":"Jao tebi, Moabe! Umišljen si, narode Kemošev! Jer sinove tvoje u izgnanstvo odvedoše, kćeri tvoje u progonstvo."},{"v":47,"t":"Ali ću promijeniti udes Moabov u budućnosti” - riječ je Jahvina. Dovde suđenje Moabu."}]},"49":{"hr":[{"v":1,"t":"O sinovima Amonovim. Ovako govori Jahve: “Izrael nema sinova, nema nasljednika? Zašto je Milkom baštinio Gad i narod se njegov nastanio u njegovim gradovima?"},{"v":2,"t":"Zato, evo, dolaze dani - riječ je Jahvina - i učinit ću da se zaore ratni krikovi u Rabi sinova Amonovih, i ona će biti humak poharani, i naseobine njene ognjem popaljene. Tada će Izrael opljačkati svoje pljačkaše” - govori Jahve."},{"v":3,"t":"“Plači, Hešbone, jer Ar je opustošen, zapomažite kćeri rapske. Opašite kostrijet, tužbalice povedite, obilazite s urezima. Jer Milkom mora u izgnanstvo sa svećenicima i knezovima."},{"v":4,"t":"Što se dičiš dolinom svojom, kćeri odmetnice, koja se uzdaš u bogatstvo svoje i govoriš: 'Tko se usuđuje ustati protiv mene?'"},{"v":5,"t":"Evo, svaljujem na te stravu odasvud uokolo: bit ćete raspršeni, svak' na svoju stranu, i nitko bjegunce neće skupiti."},{"v":6,"t":"Ali uto ću opet promijeniti udes sinova Amonovih” - riječ je Jahvina."},{"v":7,"t":"O Edomu. Ovako govori Jahve nad Vojskama: “Zar nema više mudrosti u Temanu, zar u razumnih nesta svj§eta, zar se izvjetrila mudrost njihova?"},{"v":8,"t":"Bježite, gubite se i duboko se sakrijte, stanovnici Dedana, jer Ezavu propast nosim, vrijeme kazne njegove."},{"v":9,"t":"Dođu li trgači k tebi, ni pabirka neće ostaviti; dođu li kradljivci noćni, opljačkat će sve što žele."},{"v":10,"t":"Jer ja sam onaj što će Ezava pretražiti i skrovišta mu otkriti da se ne mogne sakriti. Pleme je njegovo opustošeno: nema ga više! Nitko ne kaže:"},{"v":11,"t":"'Ostavi siročad svoju, ja ću je prehraniti i neka se udovice tvoje u me pouzdaju!'”"},{"v":12,"t":"Jer ovako govori Jahve: “Gle, oni koji odista ne bi morali piti čašu moraju je iskapiti, i zar upravo ti da ostaneš nekažnjen? Ne, ti nećeš ostati nekažnjen, morat ćeš čašu ispiti!"},{"v":13,"t":"Jer samim se sobom zakleh - riječ je Jahvina: Bosra će postati ruglo i sramota, pustinja i prokletstvo; a svi njezini gradovi bit će vječne razvaline.”"},{"v":14,"t":"Jahve mi vijest uputi, glasnik bi poslan k narodima: “Skupite se! Krenite na nj, krenite! Ustajte! U boj!"},{"v":15,"t":"Jer, gle, učinit ću te malim među narodima, prezrenim među ljudima."},{"v":16,"t":"Strah te tvoj zaveo, uznositost srca tvoga, ti koji živiš u pećinama kamenim i držiš se visova planinskih te viješ gnijezdo na timoru, k'o orlovi, odande ću te strovaliti” - riječ je Jahvina."},{"v":17,"t":"“Edom će postati pustoš; tko god njime prođe, zaprepastit će se i zviždati zbog svih rana njegovih."},{"v":18,"t":"Razorit će ga kao Sodomu i Gomoru i susjede njihove” - govori Jahve. Čovjek ondje neće stanovati, sin čovječji neće u njem boraviti."},{"v":19,"t":"“Gle, kao lav on izlazi iz guštare jordanske na pašnjake vječno zelene. Ali ću ga učas otjerati i smjestiti ondje svog izabranika. Jer tko je meni ravan? I tko će mene na račun pozvati? I koji će mi pastir odoljeti?”"},{"v":20,"t":"Zato čujte što je Jahve naumio učiniti Edomu, čujte što je nakanio protiv stanovnika Temana: i najsitniju jagnjad on će odvući, i sam njihov pašnjak zgrozit će se nad njima."},{"v":21,"t":"Od lomljave pada njina zemlja će se potresti, razlijegat će se vapaj do Crvenog mora!"},{"v":22,"t":"Gle, poput orla on se diže i lebdi, nad Bosrom širi krila. U dan onaj srce će junaka edomskih biti kao srce žene u trudovima."},{"v":23,"t":"O Damasku. Smeteni su Hamat i Arpad jer zlu vijest čuše. Srce im se steže od užasa i smirit se ne može."},{"v":24,"t":"Obeshrabren je Damask, u bijeg udario, strah ga spopao, tjeskoba i bolovi obuzeli ga kao porodilju."},{"v":25,"t":"Kako? Napušten je slavni grad, grad radosti moje!"},{"v":26,"t":"Zato će mladići njegovi popadati po trgovima, svi će ratnici poginuti u onaj dan - riječ je Jahve nad Vojskama."},{"v":27,"t":"“Potpalit ću vatrom zidine Damaska: plamen će proždrijeti dvor Ben-Hadadov.”"},{"v":28,"t":"O Kedaru i kraljevstvima hasorskim koje je potukao Nabukodonozor, kralj babilonski. Ovako govori Jahve: “Ustajte, na Kedar navalite, uništite sinove Istoka!"},{"v":29,"t":"Nek' im se oduzmu šatori i stada, šatorska krila i sva im oprema! Neka im se deve odvedu, i nek' viču na njih: 'Strava odasvud!'"},{"v":30,"t":"Bježite glavom bez obzira, duboko se skrijte, žitelji Hasora - riječ je Jahvina. Jer Nabukodonozor, kralj babilonski, snuje naum protiv vas, navalu smišlja:"},{"v":31,"t":"'Ustajte, udarite na mirni narod što živi bez straha - riječ je Jahvina - što nema vrata ni zasuna, što u osami prebiva!"},{"v":32,"t":"Deve njihove bit će plijen, mnoštvo ovaca otimačina!' I raspršit ću ih na sve strane, one ljude obrijanih zalizaka, i dovest ću odasvud na njih nesreću - riječ je Jahvina."},{"v":33,"t":"Hasor će postati brlog čagaljski i pustinja vječna. Čovjek ondje neće prebivati, neće se ondje nastaniti sin čovječji.”"},{"v":34,"t":"Riječ koju Jahve uputi proroku Jeremiji o Elamu, u početku kraljevanja Sidkije, kralja judejskoga."},{"v":35,"t":"Ovako govori Jahve nad Vojskama: “Lomim, evo, luk Elamov, srž snage njegove."},{"v":36,"t":"Četiri ću vjetra dognati na Elam sa četiri kraja neba i raspršit Elamce u sva četiri vjetra, i neće biti naroda kamo neće stići bjegunci elamski."},{"v":37,"t":"Utjerat ću Elamcima strah u kosti pred njihovim dušmanima. Pustit ću na njih nesreću, oganj gnjeva svojega. Poslat ću mač za njima dok ne budu sasvim uništeni."},{"v":38,"t":"I postavit ću u Elamu prijesto svoj i zatrt ću ondje kralja i sve knezove” - riječ je Jahvina."},{"v":39,"t":"Ali ću okrenut' udes Elama” - riječ je Jahvina."}]},"50":{"hr":[{"v":1,"t":"Riječ koju Jahve reče protiv Babilona, protiv zemlje kaldejske:"},{"v":2,"t":"“Objavite narodima! Razglasite, ne tajite, recite: Zauzet je Babilon! Bel je postiđen: Marduk razbijen! Posramljeni su kipovi njegovi, razmrskani njegovi likovi."},{"v":3,"t":"Jer sa sjevera na nj se diže narod koji će mu zemlju prometnuti u pustinju; nitko više neće u njoj živjeti, i ljudi i stoka pobjeći će i otići."},{"v":4,"t":"U one dane i u vrijeme ono - riječ je Jahvina - vratit će se sinovi Izraelovi, ići će plačuć' i tražeći Jahvu, Boga svojega."},{"v":5,"t":"Pitat će za put na Sion, onamo će pogled upravljati: 'Hodite, prionimo uz Jahvu Savezom vječnim, nezaboravnim!'"},{"v":6,"t":"K'o izgubljene ovce bijaše narod moj, pastiri ih zavedoše te zalutaše po brdima: moradoše s brda na brežuljke, zaboraviše gdje su im torovi."},{"v":7,"t":"Tko ih nađe, proždire ih, neprijatelji njini zborahu: 'Nismo mi krivi, jer zgriješiše Jahvi, pašnjaku pravde, Jahvi, nadi otaca svojih!'"},{"v":8,"t":"Bježite iz Babilona! Izađite iz zemlje kaldejske! Budite poput ovnova pred stadom."},{"v":9,"t":"Jer evo ću dići i dovesti na Babilon mnoštvo velikih naroda; u zemlji sjevernoj svrstat će se protiv njega - odanle će biti osvojen. Strijele su im k'o u sretna junaka, prazne se ne vraćaju."},{"v":10,"t":"Kaldeja će biti oplijenjena, do mile volje nju će pljačkati” - riječ je Jahvina."},{"v":11,"t":"“Da! Radujte se samo i klikujte, vi pljačkaši moje baštine! Poskakujte k'o june na paši! Ržite kao ždrebad!"},{"v":12,"t":"Mati vaša teško se osramoti, postidi se roditeljka vaša. Evo, posljednja je među narodima: pustinja, zemlja prljuša."},{"v":13,"t":"Zbog gnjeva Jahvina bit će bez življa, sva će opustjeti. Tko god prođe mimo Babilon, zgrozit će se i zviždat će nad njegovim ranama."},{"v":14,"t":"Svrstajte se protiv Babilona, opkolite ga. Strijelci, strijeljajte na nj, ne žalite strelica - Jahvi je zgriješio."},{"v":15,"t":"Sa svih strana nek' zaore poklici bojni. On se predaje! Stupovi mu padaju, bedemi se ruše: to Jahvina je osveta! Osvetite se Babilonu, vratite mu milo za drago!"},{"v":16,"t":"Istrijebite Babilonu i sijača i žeteoca što srpom zamahuje u dane žetvene! Pred mačem silničkim nek' svak' se vrati svome narodu, neka bježi zemlji svojoj.”"},{"v":17,"t":"Izrael bijaše stado razagnano, lavovi ga raspršiše. Prvi ga kralj asirski proždrije, a onda mu Nabukodonozor, kralj babilonski, kosti polomi."},{"v":18,"t":"Zato ovako govori Jahve nad Vojskama, Bog Izraelov: “Evo, kaznit ću kralja babilonskoga i zemlju njegovu, kao što kaznih kralja asirskoga."},{"v":19,"t":"I vratit ću Izraela pašnjaku njegovu da pase po Karmelu, Bašanu, brdima efrajimskim i u Gileadu, da se sit najede."},{"v":20,"t":"U one dane, u vrijeme ono - riječ je Jahvina - tražit će grijeh Izraelov, ali ga više neće biti; tražit će opačine judejske, ali ih neće naći. Jer oprostih svima koje sačuvah.”"},{"v":21,"t":"“Na zemlju meratajimsku! Kreni na nju i na stanovnike Pekoda, zatri ih do temelja, uništi iza njih sve - riječ je Jahvina - izvrši sve kako ti zapovjedih!”"},{"v":22,"t":"Ratna se vika čuje u zemlji, poraz strašan."},{"v":23,"t":"O, kako li je skršen, razbijen malj cijele zemlje! Kako li Babilon posta strašilo narodima!"},{"v":24,"t":"Zamku ti metnuh, Babilone, ti se uhvati i ne vidje. Zatečen si i uhvaćen, jer se s Jahvom zarati!"},{"v":25,"t":"Jahve otvori svoju oružnicu, izvuče oružje gnjeva svojega, jer ima posla za Jahvu nad Vojskama u zemlji kaldejskoj."},{"v":26,"t":"Udarite na nju sa svih strana, otvorite žitnice njene, slažite je kao snoplje, zatrite Babilon kletim uništenjem, da od njega ne ostane ništa."},{"v":27,"t":"Pokoljite svu junad njegovu, u klaonicu neka siđu! Jao njima, došao je njihov dan, vrijeme kazne njihove!"},{"v":28,"t":"Čujder glasa onih što pobjegoše, što utekoše iz zemlje babilonske da jave na Sionu osvetu Jahve, Boga našega, osvetu Hrama njegova!"},{"v":29,"t":"Sazovite na Babilon strijelce, sve što zapinju lukove, opkolite ga sa svih strana: nitko da ne uteče! Platite mu po zasluzi, vratite mu milo za drago, jer bi se oholio na Jahvu, Sveca Izraelova."},{"v":30,"t":"Zato će mu svi mladići popadati po trgovima i svi će mu ratnici u onaj dan izginuti - riječ je Jahvina."},{"v":31,"t":"“Evo me na te, Oholice!” - riječ je Gospoda Jahve nad Vojskama - “došao je dan tvoj, vrijeme pohoda na te."},{"v":32,"t":"Oholica će posrnuti, pasti, i nitko ga neće podići. Oganj ću podmetnuti gradovima njegovim i proždrijet će sve uokolo.”"},{"v":33,"t":"Ovako govori Jahve nad Vojskama: “Potlačeni su sinovi Izraelovi, zajedno sa sinovima Judinim. Oni što ih zarobiše, drže ih čvrsto i neće da ih puste."},{"v":34,"t":"Ali, moćan je njihov Otkupitelj, ime mu Jahve nad Vojskama. On će obraniti parnicu njihovu - zemlji mir donijeti i smesti pučanstvo Babilona.”"},{"v":35,"t":"Mač na Kaldejce - riječ je Jahvina - na pučanstvo Babilona, na knezove i mudrace njegove!"},{"v":36,"t":"Mač na brbljavce njegove, neka polude! Mač na njegove ratnike, neka se prestrave!"},{"v":37,"t":"Mač na njegove konje i bojna kola i na svu gomilu posred njega: nek postanu kao žene! Mač na njihove riznice; nek ih opljačkaju!"},{"v":38,"t":"Mač na vode njihove, neka presahnu! Jer to je zemlja idola, zaludiše ih kipovi, strašila njihova."},{"v":39,"t":"Zato će se ondje nastaniti risovi s čagljima, i nojevi će ondje obitavat. Dovijeka će ostat' mjesto bez življa, nitko ondje neće živjeti od koljena do koljena."},{"v":40,"t":"Razorit će ga kao što Bog razori Sodomu i Gomoru i susjede njihove - riječ je Jahvina. Čovjek ondje neće stanovati, sin čovječji neće u njem' boraviti."},{"v":41,"t":"Evo dolazi narod sa Sjevera, puk velik i mnogi kraljevi, i dižu se s krajeva zemlje."},{"v":42,"t":"U ruci im luk i koplje, okrutni su, nemilosrdni. Graja im buči poput mora, jašu na konjima, kao jedan za boj spremni protiv tebe, kćeri babilonska."},{"v":43,"t":"Kralj babilonski ču vijest o njima: i ruke mu klonuše, muka ga spopade, bolovi ga obuzeše kao porodilju."},{"v":44,"t":"“Gle, kao lav on izlazi iz guštare jordanske na pašnjake vječno zelene. Al' ja ću ga učas otjerati i smjestiti ondje svog izabranika. Jer, tko je meni ravan? I tko će mene na račun pozvati? I koji će mi pastir odoljeti?”"},{"v":45,"t":"Zato, čujte što je Jahve naumio da učini Babilonu, čujte što je nakanio protiv zemlje kaldejske: i najsitniju jagnjad on će odvući; i sam njihov pašnjak zgrozit će se nad njima."},{"v":46,"t":"Na glas da je pao Babilon zemlja će se potresti: razlijegat će se vapaj među narodima."}]},"51":{"hr":[{"v":1,"t":"Ovako govori Jahve: “Gle, ja podižem protiv Babilona i protiv pučanstva kaldejskog vjetar zatornički."},{"v":2,"t":"Poslat ću na Babilon vijače da ga viju i prorešetaju zemlju njegovu. Kad ga sa svih strana opkole u kobni dan,"},{"v":3,"t":"nek' strijelac luka ne odlaže, nek' ne skida oklopa! Ne štedite mladića njihovih, svu mu vojsku kleto uništite!"},{"v":4,"t":"Pobijeni će padati po zemlji kaldejskoj, probodeni po ulicama njegovim.”"},{"v":5,"t":"Ne, Izrael - Judeja - nije udovica Boga svojega, Jahve nad Vojskama, iako je zemlja njihova puna krivice protiv Sveca Izraelova."},{"v":6,"t":"Bježite iz Babilona, nek' svak' spasi život svoj, da ne izginete s njegova bezakonja, jer ovo je vrijeme Jahvine odmazde, svakom plaća po zasluzi!"},{"v":7,"t":"Babilon bijaše pehar zlatni u ruci Jahvinoj, pehar koji opi svijet cijeli. Vinom tim se puci opiše, i zato se puci obezumiše."},{"v":8,"t":"Iznenada pade Babilon, razmrskan: zakukajte nad njim! Potražite balzama rani njegovoj: možda će ozdravit'!"},{"v":9,"t":"Liječili smo Babilon, al' se ne izliječi. Pustimo ga, vratimo se svaki u svoj kraj! Jer do neba dopire njegova osuda i diže se pod oblake."},{"v":10,"t":"Jahve je iznio pravdu našu! Hajde da Sionu objavimo djelo Jahve, Boga našega."},{"v":11,"t":"Naoštrite strelice, napunite tobolce! Jahve potače duh kraljeva medijskih jer naumi zatrti Babilon, Jahvina je to osveta, osveta za Hram njegov."},{"v":12,"t":"Razvijte stijeg, zidine babilonske! Pojačajte straže! Postavite stražare! Razmjestite zasjede! Jer Jahve što naumi to sad izvodi, kako je rekao protiv Babilona."},{"v":13,"t":"O, ti što prebivaš na velikim vodama i bogat blagom svakojakim! Sad ti svršetak dođe, kraj tvojoj lakomosti."},{"v":14,"t":"Životom svojim zakle se Jahve nad Vojskama: “Napunit ću te ljudstvom kao skakavcima, zaorit će protiv tebe vika bojna.”"},{"v":15,"t":"On snagom svojom stvori zemlju, mudrošću svojom uspostavi krug zemaljski i umom svojim razape nebesa."},{"v":16,"t":"Kad mu glas zaori, huče vode na nebesima, oblake diže s kraja zemlje: stvara kiši munje, vjetar izvodi iz skrovišta njegovih."},{"v":17,"t":"Svakom čovjeku pamet stane, svaki se zlatar zastidi svoga kipa, jer svi su mu kipovi samo varka, nema u njima duha."},{"v":18,"t":"Isprazni su oni, smiješne tvorevine, propast će u dan kazne."},{"v":19,"t":"'Jakovljev dio' nije kao oni: jer on je sve stvorio, Izrael pleme je baštine njegove. Jahve nad Vojskama ime je njegovo."},{"v":20,"t":"Ti si mi bio malj, oružje ratno. Pomlatih tobom narode, razmrskah tobom kraljevstva."},{"v":21,"t":"Pomlatih tobom konja i konjanika, pomlatih tobom bojna kola i vozača."},{"v":22,"t":"Pomlatih tobom čovjeka i ženu, pomlatih tobom starca i dijete. Pomlatih tobom mladića i djevojku, pomlatih tobom pastira i stado."},{"v":23,"t":"Pomlatih tobom ratara i zapregu njegovu, pomlatih tobom namjesnike i upravljače."},{"v":24,"t":"Ali na vaše oči sada plaća Babilonu i svim Kaldejcima za sve zlo koje učiniše Sionu - riječ je Jahvina."},{"v":25,"t":"“Evo me na te, Goro zatornice - riječ je Jahvina - zatornice svega svijeta! Zamahnut ću rukom protiv tebe, svalit ću te s litice, pretvorit ću te u goru spaljenu."},{"v":26,"t":"Iz tebe više neće klesati kamen ugaoni ni kamen temeljac, bit ćeš vječna pustinja” - riječ je Jahvina."},{"v":27,"t":"Podignite stijeg u zemlji, zatrubite u rog među narodima! Pripremite na nj narode, sazovite na nj kraljevstva - Ararat, Mini, Aškenaz! Postavite protiv njega pozivnike, nek' nasrnu konji k'o dlakavi skakavci!"},{"v":28,"t":"Spremite na nj narode, kraljeve medijske, vojvode i namjesnike njihove i svu zemlju kojom vladaju."},{"v":29,"t":"Zemlja će se tresti, drhtati, kad se stanu uspinjati k Babilonu svi naumi Jahvini da pretvori zemlju babilonsku u pustinju nenastanjenu."},{"v":30,"t":"Nebojše babilonske odustaše od borbe, u utvrdama posjedaše, nesta sile njihove: postadoše kao žene. Spaljeni su domovi njihovi, polomljeni zasuni na vratima."},{"v":31,"t":"Teklič tekliča prestiže, glasnik juri za glasnikom, da jave kralju babilonskom da mu je grad sa svih strana zauzet,"},{"v":32,"t":"prijelazi zaposjednuti, tvrđave ognjem popaljene, a ratnici prestrašeni."},{"v":33,"t":"Jer ovako govori Jahve, Bog Izraelov: “Kći je babilonska kao gumno u vrijeme kad se po njem gazi; još malo, i doći će joj vrijeme žetve.”"},{"v":34,"t":"Izjeo me, satro babilonski kralj, odgurnuo me kao prazan pladanj, k'o zmaj me on progutao, napunio trbušinu, iz mog me istjerao Edena."},{"v":35,"t":"“Nasilje i patnje moje na Babilon!” govore stanovnici Siona. “Krv moja na Kaldejce!” govori Jeruzalem."},{"v":36,"t":"Zato ovako govori Jahve: “Gle, ja ću braniti parnicu tvoju i krvavo te osvetiti. Sasušit ću more njegovo i presahnut ću izvore njegove."},{"v":37,"t":"Babilon će biti hrpa ruševina, brlog čagljima, užas i ruglo, kraj nenastanjen."},{"v":38,"t":"Svi zajedno riču k'o lavovi, zavijaju kao lavići."},{"v":39,"t":"Kad se ugriju, priredit će im pijanku, napojiti ih da se provesele, da zaspe vječnim snom, da se više ne probude - riječ je Jahvina."},{"v":40,"t":"Odvest ću ih k'o janjce na klanje, kao jarce i ovnove.”"},{"v":41,"t":"“Kako li je zauzet, kako osvojen taj ponos zemlje sve? Kako li Babilon posta strašilo narodima?"},{"v":42,"t":"Uzdiglo se more protiv Babilona, prekrilo ga valovlje njegovo."},{"v":43,"t":"Gradovi mu pustoš postali, zemlja suha, pustara: čovjek u njoj ne stanuje, niti njom prolazi sin čovječji.”"},{"v":44,"t":"“Kaznit ću Bela babilonskog, iz ralja mu otet što je progutao. Neće više k njemu hrliti narodi, srušit će se babilonske zidine."},{"v":45,"t":"Izađi iz njega, narode moj! Nek' svaki spasi život svoj od jarosnoga gnjeva Jahvina!"},{"v":46,"t":"Neka vam srce ne klone! Ne bojte se glasÄa što se zemljom šire, jedne godine ovakvi, druge onakvi, i što u zemlji vlada nasilje, te silnik za silnikom ustaje."},{"v":47,"t":"Jer evo dolaze dani kada ću kazniti kipove babilonske, i sva će mu se zemlja postidjeti, i svi će mu pobijeni ležat' posred grada."},{"v":48,"t":"Tada će nad Babilonom klicati nebo i zemlja i sve što je na njima, jer će sa sjevera navaliti na grad, zatornici njegovi - riječ je Jahvina!"},{"v":49,"t":"I Babilon mora pasti za pobijene Izraelce, kao što su za Babilon padali pobijeni po svem svijetu."},{"v":50,"t":"Vi što umakoste maču, idite, ne ostajte ovdje. Spominjite se Jahve u zemlji dalekoj, i neka vam Jeruzalem bude na srcu:"},{"v":51,"t":"'Stidjeli smo se slušajuć' sramotu, rumenilo nam prekrilo lice kad ono tuđinci nahrupiše u Svetište Doma Jahvina.'"},{"v":52,"t":"Zato, evo, dolaze dani - riječ je Jahvina - kad ću kazniti kipove njegove i po svoj će mu zemlji stenjat' ranjenici."},{"v":53,"t":"Da se Babilon popne do neba, da se utvrdi na visu nedostupnu, na moju će zapovijed na nj navalit' pustošnici” - riječ je Jahvina."},{"v":54,"t":"Čujte vapaj iz Babilona, i strašan poraz iz zemlje kaldejske!"},{"v":55,"t":"Jer sam Jahve pustoši Babilon, on stišava strašnu buku njegovu: bučili su vali njegovi k'o vode velike, razlijegala se huka njihova."},{"v":56,"t":"Jest, pustošnik dođe na Babilon, uhvaćeni su ratnici njegovi, lukovi im polomljeni. Zaista, Jahve je Bog osvetnik koji plaća po zasluzi!"},{"v":57,"t":"“Opojit ću mu knezove i mudrace, vojvode, namjesnike i ratnike: da zaspe vječnim snom pa se više ne probude” - govori Kralj, ime mu je Jahve nad Vojskama."},{"v":58,"t":"Ovako govori Jahve nad Vojskama: “Široke zidine babilonske bit će do temelja razvaljene, a visoka trava njegova bit će ognjem spaljena. Narodi se zalud trudili, puci se za oganj mučili!”"},{"v":59,"t":"Evo zapovijedi što je prorok Jeremija dade Seraji, sinu Mahsejina sina Nerije, kad je Seraja krenuo u Babilon sa Sidkijom, kraljem judejskim, četvrte godine njegova vladanja. Seraja bijaše veliki komornik."},{"v":60,"t":"Jeremija je u jednu knjigu bio zapisao svu nesreću koja je morala doći na Babilon - sva ona proroštva napisana protiv Babilona."},{"v":61,"t":"Jeremija reče Seraji: “Kad dođeš u Babilon, išti prigodu da obznaniš sve ove riječi."},{"v":62,"t":"I reci: 'Jahve, ti sam reče da ćeš zatrti ovo mjesto te u njemu ničega više neće biti, ni čovjeka ni živinčeta, nego će postati vječna pustinja.'"},{"v":63,"t":"Kad pročitaš ovu knjigu, zaveži je za kamen i baci uEufrat."},{"v":64,"t":"I reci: 'Ovako će potonuti Babilon i neće se više podići iz nesreće koju ću na nj svaliti.'” To su riječi Jeremijine."}]},"52":{"hr":[{"v":1,"t":"Sidkiji je bila dvadeset i jedna godina kad se zakraljio, a kraljevao je jedanaest godina u Jeruzalemu. Materi mu bijaše ime Hamitala, kćerka Jeremije, i bila je iz Libne."},{"v":2,"t":"Činio je što je zlo u očima Jahvinim, sve kao što je činio Jojakin."},{"v":3,"t":"To je zadesilo Jeruzalem zbog gnjeva Jahvina; Jahve ih napokon i odbaci ispred lica svoga. Sidkija se pobunio protiv babilonskog kralja."},{"v":4,"t":"Devete godine njegova kraljevanja, desetoga dana desetoga mjeseca, krenu sam babilonski kralj Nabukodonozor sa svom svojom vojskom na Jeruzalem. Utabori se pred gradom i opasa ga opkopom."},{"v":5,"t":"Grad osta opkoljen sve do jedanaeste godine Sidkijina kraljevanja."},{"v":6,"t":"Devetoga dana četvrtoga mjeseca, kad je u gradu zavladala takva glad da priprosti puk nije imao ni kruha,"},{"v":7,"t":"neprijatelj provali u grad. Tada kralj i svi ratnici pobjegoše noću kroz vrata između dva zida nad Kraljevskim vrtom - Kaldejci bijahu opkolili grad - i krenuše putem prema Arabi."},{"v":8,"t":"Kaldejske čete nagnuše za njim u potjeru i sustigoše Sidkiju na Jerihonskim poljanama, a sva se njegova vojska razbježala."},{"v":9,"t":"I Kaldejci uhvatiše kralja i odvedoše ga u Riblu, u zemlji hamatskoj, pred kralja babilonskog, koji mu izreče presudu."},{"v":10,"t":"Pokla Sidkijine sinove pred njegovim očima, pobi u Ribli sve Judine knezove;"},{"v":11,"t":"Sidkiji iskopa oči i okova ga verigama i odvede u Babilon, gdje ga je držao u tamnici sve do smrti njegove."},{"v":12,"t":"Desetoga dana petoga mjeseca - devetnaeste godine kraljevanja Nabukodonozora, kralja babilonskog - uđe u Jeruzalem Nebuzaradan, zapovjednik tjelesne straže."},{"v":13,"t":"On zapali Dom Jahvin, kraljevski dvor i sve kuće u Jeruzalemu, osobito kuće uglednika;"},{"v":14,"t":"kaldejske čete, pod zapovjednikom tjelesne straže, razoriše zidine oko Jeruzalema."},{"v":15,"t":"Nebuzaradan, zapovjednik tjelesne straže, odvede u sužanjstvo ostatak naroda koji bijaše ostao u gradu, a tako i prebjege babilonskom kralju i ostalu svjetinu."},{"v":16,"t":"Neke od malih ljudi Nebuzaradan ostavi u zemlji kao vinogradare i ratare."},{"v":17,"t":"Kaldejci razbiše tučane stupove u Domu Jahvinu, podnožja i mjedeno more u Domu Jahvinu, i tuč odniješe u Babilon."},{"v":18,"t":"Uzeše i lonce, lopate, noževe, posudice i uopće sav tučani pribor koji se upotrebljavao za bogoslužja."},{"v":19,"t":"Zapovjednik uze i umivaonice, kadionice, škropionice, lonce, svijećnjake, zdjele, žrtvene pehare, uopće sve što bijaše od zlata i srebra,"},{"v":20,"t":"dva stupa, jedno more i dvanaest tučanih volova pod morem, podnožja što je kralj Salomon dao izraditi za Dom Jahvin. Nije moguće procijeniti koliko je tuča bilo u svim tim predmetima."},{"v":21,"t":"Prvi stup bijaše visok osamnaest lakata - obuhvatiti ga je mogao konop od dvanaest lakata - bijaše četiri prsta debeo, a šupalj."},{"v":22,"t":"Imao je glavicu od tuča, visoku pet lakata; i obvijaše je oplet i mogranji, a sve od tuča. Takav je bio i drugi stup."},{"v":23,"t":"A devedeset i šest šipaka slobodno je visjelo. Sve u svemu bijaše oko sto šipaka u tom opletu."},{"v":24,"t":"Zapovjednik je straže odveo svećeničkog poglavara Seraju, drugog svećenika, Sefaniju, i tri čuvara praga."},{"v":25,"t":"Iz grada je odveo jednog dvorjanina, vojničkog zapovjednika, sedam ljudi iz kraljeve pratnje koji se zatekoše u gradu, pisara zapovjednika vojske koji je novačio puk te šezdeset pučana koji se također zatekoše u gradu."},{"v":26,"t":"Zapovjednik tjelesne straže Nebuzaradan odvede ih pred kralja babilonskog u Riblu."},{"v":27,"t":"I kralj babilonski zapovjedi da ih pogube u Ribli, u zemlji hamatskoj. Tako su judejski narod odveli s njegove rodne grude."},{"v":28,"t":"Evo broja ljudstva što ga Nabukodonozor odvede u sužanjstvo: sedme godine tri tisuće i dvadeset tri Judejca;"},{"v":29,"t":"osamnaeste godine Nabukodonozorove osamsto trideset i dvije osobe iz Jeruzalema;"},{"v":30,"t":"dvadeset i treće godine Nabukodonozorove, Nebuzaradan, zapovjednik tjelesne straže, odvede sedam stotina četrdeset i pet Judejaca. U svemu: četiri tisuće i šest stotona osoba."},{"v":31,"t":"A trideset i sedme godine otkako je zasužnjen judejski kralj Jojakin, dvadeset i petoga dana dvanaestoga mjeseca, babilonski kralj Evil Merodak u prvoj godini svoje vladavine pomilova judejskoga kralja Jojakina i pusti ga iz tamnice."},{"v":32,"t":"Ljubezno je s njim razgovarao i stolicu mu postavio više nego drugim kraljevima koji bijahu s njim u Babilonu."},{"v":33,"t":"Jojakin je odložio svoje tamničke haljine i jeo s kraljem za istim stolom svega svoga vijeka."},{"v":34,"t":"Do kraja njegova života, sve do smrti, babilonski mu je kralj trajno, iz dana u dan, davao uzdržavanje."}]}},"LAM":{"1":{"hr":[{"v":1,"t":"Kako osamljena sjedi prijestolnica, nekoć naroda puna; postade kao udovica, nekoć velika među narodima. Vladarica nad pokrajinama, na tlaku sad ide."},{"v":2,"t":"Noći provodi gorko plačući, suzama pokriva obraze. Nikog nema da je utješi, od svih koji su je ljubili. Svi je prijatelji iznevjeriše i postaše joj neprijatelji."},{"v":3,"t":"Izagnan je Juda, u nevolji je i u progonstvu teškom. Sad živi među poganima, ne nalazi počinka. Svi ga gonitelji sustižu u tjesnacima."},{"v":4,"t":"Putovi sionski tuguju jer nitko ne dolazi na svetkovine. Sva su vrata razvaljena, svećenici uzdišu, ucviljene su djevice njegove, a on je pun gorčine."},{"v":5,"t":"Tlačitelji njegovi sada gospodare, neprijatelji likuju: Jahve ga ucvili zbog grijeha njegovih premnogih. Djeca mu otišla u izgnanstvo pred tlačiteljem."},{"v":6,"t":"Povukla se od Kćeri sionske sva slava njezina. Knezovi joj postadoše k'o ovnovi koji paše ne nalaze; nemoćni vrludaju ispred goniča."},{"v":7,"t":"Jeruzalem se spominje danÄa bijede i lutanja, kad mu narod dušmanu u ruke pade a nitko mu pomoći ne pruži. Tlačitelji ga gledahu smijući se njegovoj propasti."},{"v":8,"t":"Teško sagriješi Jeruzalem, postade kao nečistoća ženina. Svi što ga štovahu, sada ga preziru: jer vidješe golotinju njegovu. On samo plače i natrag se okreće."},{"v":9,"t":"Skuti su mu uprljani, nije ni sanjao što ga čeka. Duboko je pao, a nikog da ga tješi. “Pogledaj, Jahve, moju nevolju: jer neprijatelj likuje.”"},{"v":10,"t":"Neprijatelj poseže rukom za svim dragocjenostima njegovim. Gledao je gdje pogani provaljuju u njegovo Svetište, oni kojima si zabranio i pristup u svoj zbor."},{"v":11,"t":"Sav narod njegov jeca, tražeći kruha; svi daju dragulje za hranu da bi ponovo živnuli. Evo, Jahve, pogledaj kako sam prezren."},{"v":12,"t":"Svi vi što putem prolazite, pogledajte i vidite ima li boli kakva je bol kojom sam ja pogođen, kojom me Jahve udari u dan žestokog gnjeva svoga!"},{"v":13,"t":"S visine pusti oganj, utjera ga u kosti moje. Pred noge mrežu mi razape i tako me nauznak obori; ucvili me, ožalosti za sva vremena."},{"v":14,"t":"Natovario me mojim grijesima, rukom ih svojom pritegnuo; na vrat mi ih navalio, snagu mi oduzeo. Predao me Gospod u ruke njihove, ne mogu se uspraviti."},{"v":15,"t":"Sve junake iz moje sredine Gospod odbaci: digao je zbor protiv mene da uništi uzdanicu moju. U tijesku izgazi Gospod mene, djevicu, kćerku Judinu."},{"v":16,"t":"Zato moram plakati, oči mi suze liju, jer daleko je od mene moj tješitelj da mi duh povrati. Sinovi su moji poraženi, odveć silan bijaše neprijatelj."},{"v":17,"t":"Sion pruža ruke: nema mu tješitelja. Jahve je protiv Jakova sa svih strana pozvao tlačitelje; i tako Jeruzalem postade među njima strašilo."},{"v":18,"t":"Jahve, on je pravedan; jer riječi se njegovoj protivih. Oh, čujte, narodi svi, gledajte moju bol: djevice moje, moji mladići, svi odoše u izgnanstvo!"},{"v":19,"t":"Pozvah sve ljubavnike svoje, ali me oni prevariše. Moji svećenici i starješine pogiboše u gradu tražeći hrane da bi ponovo živnuli."},{"v":20,"t":"Pogledaj, Jahve, u kakvoj sam tjeskobi, moja utroba strepi, srce mi se u grudima grči jer bijah opako prkosan! Vani mač pokosi moje sinove, a unutra - smrt."},{"v":21,"t":"Čuj kako stenjem: nema mi tješitelja! Svi neprijatelji čuju za moju nesreću i likuju što si to učinio! Daj da dođe dan što si ga objavio, da njima bude kao meni."},{"v":22,"t":"Neka se pokaže sva njina zloća pred licem tvojim, a onda postupaj s njima kao što si sa mnom postupio za sve grijehe moje! Jer samo uzdišem, a srce moje tuguje."}]},"2":{"hr":[{"v":1,"t":"Kako mrakom zastrije Gospod u svom gnjevu Kćer sionsku. S neba na zemlju baci slavu Izraelovu! I ne sjeti se podnožja svoga u dan gnjeva svojega!"},{"v":2,"t":"Bez milosti Gospod satrije sve stanove Jakovljeve, u svom gnjevu razori tvrđave kćeri Judine; sa zemljom je sravnio i prokleo kraljevstvo i njegove knezove."},{"v":3,"t":"U rasplamtjelom gnjevu svojem razbi svu snagu Izraelovu, povuče svoju desnicu pred neprijateljem; u Jakovu raspiri plamen ognjeni koji sve uokolo proždire."},{"v":4,"t":"Nategao je luk k'o neprijatelj, kao dušman ispružio desnicu, ubijajući sve što mu drago bijaše. Na šator Kćeri sionske sasu k'o oganj gnjev svoj jarosni."},{"v":5,"t":"K'o neprijatelj Gospod bijaše: razorio je Izraela, razorio sve dvore njegove, porušio njegove utvrde, umnožio kćeri Judinoj uzdisaje i jecaje."},{"v":6,"t":"Kao vrtu razvali mu sjenicu, razori mjesto sastanka. Baci Jahve u zaborav svetkovine i subote na Sionu; u gnjevu svojem prezre kralja i svećenika."},{"v":7,"t":"Svoj oltar je Gospod odbacio, zgadilo mu se Svetište njegovo. U ruke neprijatelja je predao bedeme svoje i dvorove. Bučili su u Domu Jahvinu, kao u dan blagdanji."},{"v":8,"t":"Jahve naumi razvaliti zidove Kćeri sionske. Nape uže mjerničko, ne ustegnu ruku od rušenja. Predziđe, zidine zavi u tugu: oronuše zajedno."},{"v":9,"t":"Vrata njina utonuše u zemlju, on im je razbio zasune; kralj i knezovi su među pucima, Zakona nema! Ni u prorokÄa više se ne nalaze viđenja Jahvina."},{"v":10,"t":"Starješine Kćeri sionske na zemlji sjede i šute, posiplju glavu prašinom, kostrijet pripasuju. K zemlji glave obaraju djevice jeruzalemske."},{"v":11,"t":"Iščilješe mi oči od suza, utroba moja ustreptala, jetra mi se na zemlju prosula zbog sloma kćeri naroda mojega, jer djeca i dojenčad umiru po trgovima Grada."},{"v":12,"t":"Govore majkama svojim: “Gdje je žito i vino?” dok obamiru kao ranjeni po trgovima Grada, dok ispuštaju dušu svoju na grudima matera svojih."},{"v":13,"t":"S čime da te prispodobim? Na koga si nalik, Kćeri jeruzalemska? S kime da te usporedim, kako utješim, djevice, Kćeri sionska? Jer kao more tvoja je nesreća neizmjerna. Tko će te iscijeliti?"},{"v":14,"t":"Viđenja tvojih proroka bijahu varka i laž, oni nisu objavili krivnju tvoju da te od izgnanstva odvrate. Varali su te utvarama lažnim i zamamnim."},{"v":15,"t":"Nad tobom plješću rukama svi koji putem prolaze, zvižde i vrte glavom zbog Kćeri jeruzalemske: “Je li to grad na glasu ljepotom, radost svemu svijetu?”"},{"v":16,"t":"Na tebe otvaraju usta svi neprijatelji tvoji, zvižde, škrguću zubima i govore: “Proždrijesmo je! To je dan za kojim čeznusmo, doživjesmo, vidjesmo!”"},{"v":17,"t":"Jahve izvrši naum svoj, održa svoju riječ koju naredi u davnim danima: nemilice te razorio. Neprijatelj likuje zbog tebe, tvoj protivnik rog svoj podiže."},{"v":18,"t":"U sav glas viči Gospodu, jecaj, Kćeri sionska! Neka k'o potok teku tvoje suze danju i noću. Ne daj počinka sebi, neka se zjenica oka tvoga ne odmori."},{"v":19,"t":"Ustani, viči noću za svake promjene straže. K'o vodu izlij srce pred licem Gospodnjim, k njemu podiži ruke i traži milost za svoju nejačad koja od glada obamire po uglovima ulica."},{"v":20,"t":"Pogledaj, Jahve, i vidi kome si to učinio. Zar žene da jedu porod svoj, djecu što njišu u naručju? Zar moradoše biti poklani u Svetištu Gospodnjem svećenici i proroci?"},{"v":21,"t":"U uličnoj prašini leže djeca i starci; moje djevice i moji mladići od mača padoše. Ti ih pomori u dan gnjeva svojega, ti ih pokla nemilice."},{"v":22,"t":"Ti si, kao na dan svečani, sa svih strana sazvao užase moje. U dan gnjeva Jahvina nitko nije preživio, nitko se nije spasio. One koje sam odnjihala i odgojila neprijatelj moj sve je istrijebio."}]},"3":{"hr":[{"v":1,"t":"Ja sam čovjek što upozna bijedu pod šibom gnjeva njegova."},{"v":2,"t":"Mene je odveo i natjerao da hodam u tmini i bez svjetlosti."},{"v":3,"t":"I upravo mene bije i udara bez prestanka njegova ruka."},{"v":4,"t":"Iscijedio je moje meso, kožu moju, polomio kosti moje."},{"v":5,"t":"Načinio mi jaram, glavu obrubio tegobama."},{"v":6,"t":"Pustio me da živim u tminama kao mrtvaci vječiti."},{"v":7,"t":"Zazidao me, i ja ne mogu izaći, otežao je moje okove."},{"v":8,"t":"Kada sam vikao i zapomagao, molitvu je moju odbijao."},{"v":9,"t":"Zazidao mi ceste tesanim kamenom, zakrčio je putove moje."},{"v":10,"t":"Meni on bijaše medvjed koji vreba, lav u zasjedi."},{"v":11,"t":"U bespuća me vodio, razdirao, ostavljao me da umirem."},{"v":12,"t":"Napinjao je luk svoj i gađao me kao metu za svoje strelice."},{"v":13,"t":"U slabine mi sasuo strelice, sinove svoga tobolca."},{"v":14,"t":"Postao sam smiješan svome narodu, rugalica svakidašnja."},{"v":15,"t":"Gorčinom me hranio, pelinom me napajao."},{"v":16,"t":"Puštao me da zube kršim kamen grizući, zakapao me u pepeo."},{"v":17,"t":"Duši je mojoj oduzet mir i više ne znam što je sreća!"},{"v":18,"t":"Rekoh: Dotrajao je život moj i nada koja mi od Jahve dolazi."},{"v":19,"t":"Spomeni se bijede moje i stradanja, pelina i otrova!"},{"v":20,"t":"Bez prestanka na to misli i sahne duša u meni."},{"v":21,"t":"To nosim u srcu i gojim nadu u sebi."},{"v":22,"t":"Dobrota Jahvina nije nestala, milosrđe njegovo nije presušilo."},{"v":23,"t":"Oni se obnavljaju svako jutro: tvoja je vjernost velika!"},{"v":24,"t":"“Jahve je dio moj”, veli mi duša, “i zato se u nj pouzdajem.”"},{"v":25,"t":"Dobar je Jahve onom koji se u nj pouzdaje, duši koja ga traži."},{"v":26,"t":"Dobro je u miru čekati spasenje Jahvino!"},{"v":27,"t":"Dobro je čovjeku da nosi jaram za svoje mladosti."},{"v":28,"t":"Neka sjedi u samoći i šuti, jer mu On to nametnu;"},{"v":29,"t":"neka usne priljubi uz prašinu, možda još ima nade!"},{"v":30,"t":"Neka pruži obraz onome koji ga bije, neka se zasiti porugom."},{"v":31,"t":"Jer Gospod ne odbacuje nikoga zauvijek:"},{"v":32,"t":"jer ako i rastuži, on se smiluje po svojoj velikoj ljubavi."},{"v":33,"t":"Jer samo nerado on ponižava i rascvili sinove čovjeka."},{"v":34,"t":"Kad se gaze nogama svi zemaljski sužnjevi,"},{"v":35,"t":"kad se izvrće pravica čovjeku pred licem Svevišnjeg,"},{"v":36,"t":"kad se krivica nanosi čovjeku u parnici, zar Gospod ne vidi?"},{"v":37,"t":"Tko je rekao nešto i zbilo se? Nije li Gospod to zapovjedio?"},{"v":38,"t":"Ne dolazi li iz usta Svevišnjega i dobro i zlo?"},{"v":39,"t":"Na što se tuže živi ljudi? Svatko na svoj grijeh."},{"v":40,"t":"Ispitajmo, pretražimo pute svoje i vratimo se Jahvi."},{"v":41,"t":"Dignimo svoje srce i ruke svoje k Bogu koji je na nebesima."},{"v":42,"t":"Da, mi smo se odmetali, bili nepokorni, a ti, ti nisi praštao!"},{"v":43,"t":"Obastrt gnjevom svojim, gonio si nas, ubijao i nisi štedio."},{"v":44,"t":"Oblakom si se obastro da molitva ne prodre do tebe."},{"v":45,"t":"Načinio si od nas smeće i odmet među narodima."},{"v":46,"t":"Razjapili usta na nas svi neprijatelji naši."},{"v":47,"t":"Užas i jama bila nam sudbina, propast i zator!"},{"v":48,"t":"Potoci suza teku iz očiju mojih zbog propasti Kćeri naroda mojega."},{"v":49,"t":"Moje oči liju suze bez prestanka, jer prestanka nema"},{"v":50,"t":"dok ne pogleda i ne vidi Jahve s nebesa."},{"v":51,"t":"Moje mi oko bol zadaje zbog kćeri svih mojega grada."},{"v":52,"t":"Uporno me k'o pticu progone svi što me mrze, a bez razloga."},{"v":53,"t":"U jamu baciše moj život i zatrpaše je kamenjem."},{"v":54,"t":"Voda mi dođe preko glave, rekoh sam sebi: “Pogiboh!”"},{"v":55,"t":"I tada zazvah ime tvoje, Jahve, iz najdublje jame."},{"v":56,"t":"Ti oču moj glas: “Ne začepljuj uši svoje na vapaje moje.”"},{"v":57,"t":"Bliz meni bijaše u dan vapaja mog, govoraše: “Ne boj se!”"},{"v":58,"t":"Ti si, Gospode, izborio pravdu za dušu moju, ti si život moj izbavio."},{"v":59,"t":"Ti, Jahve, vidje kako me tlače, dosudi mi pravdu."},{"v":60,"t":"Ti vidje svu osvetu njinu, sve podvale protiv mene."},{"v":61,"t":"Čuo si, Jahve, podrugivanje njihovo, sve podvale protiv mene."},{"v":62,"t":"Usne protivnika mojih i misli njine protiv mene su cio dan."},{"v":63,"t":"Kad sjede, kad ustaju, pogledaj samo: ja sam im pjesma-rugalica."},{"v":64,"t":"Vrati im, Jahve, milo za drago, po djelu ruku njihovih."},{"v":65,"t":"Učini da srca im otvrdnu, udari ih prokletstvom svojim."},{"v":66,"t":"Goni ih gnjevno i sve ih istrijebi pod nebesima svojim, Jahve!"}]},"4":{"hr":[{"v":1,"t":"Jao, potamnje zlato, to suho zlato! Sveto se kamenje prosu na uglovima svih ulica."},{"v":2,"t":"Sinovi sionski, nekoć cijenjeni kao najčišće zlato, ah, sada ih cijene kao sudove glinske, kao djelo ruku lončarevih!"},{"v":3,"t":"Čak i šakali pružaju dojke i doje mladunčad, ali kćeri naroda moga postaše okrutne kao nojevi u pustinji."},{"v":4,"t":"Jezik dojenčeta za nepce se lijepi od žeđi. Djeca vape za kruhom, a nikog da im ga pruži."},{"v":5,"t":"Oni što se nekoć sladiše biranim jelima ginu po ulicama; nekoć nošeni u grimizu, sada se valjaju po buništu."},{"v":6,"t":"Veći bijaše zločin Kćeri naroda moga od grijeha Sodome, što u tren oka bi razorena, a ničija se ruka ne diže na nju."},{"v":7,"t":"Njeni mladići bijahu nekoć čišći od snijega, bjelji od mlijeka, od koralja rumenija bijahu im tijela, lice glatko k'o safir."},{"v":8,"t":"Sad im je obraz crnji od čađe, ne prepoznaju se više na ulici. Koža im se lijepi za kosti, suha kao drvo."},{"v":9,"t":"Kako su sretni oni što ih mač probode, sretniji od onih koje pomori glad; koji padaju, iscrpljeni, jer im nedostaju plodovi zemljini."},{"v":10,"t":"Žene, tako nježne, kuhaše djecu svoju, njima se hraniše za propasti Kćeri naroda moga."},{"v":11,"t":"Jahve je utolio svoj bijes, izlio jarosnu srdžbu svoju, na Sionu raspirio požar što sažiže i same temelje njegove."},{"v":12,"t":"Nisu vjerovali kraljevi zemaljski ni svekoliko stanovništvo zemlje da će ugnjetač i neprijatelj ući na vrata jeruzalemska -"},{"v":13,"t":"zbog grijeha svojih prorokÄa, zbog bezakonja svećenikÄa koji usred grada prolijevahu krv pravednikÄa!"},{"v":14,"t":"K'o slijepi teturahu ulicama, omašteni krvlju, te nitko nije smio da se takne odjeće njihove."},{"v":15,"t":"“Natrag, nečisti!” - viču im. “Natrag! Ne dirajte!” I tada pobjegoše poganima, al' ne smjedoše ondje ostati."},{"v":16,"t":"Raspršilo ih lice Jahvino, on ih više nije gledao. Ne poštuju više svećenikÄa, ne sažaljuju staraca."},{"v":17,"t":"Već nam oči iščilješe iščekujući pomoć, ali uzalud; s kula naših zureć' u daljinu očekivasmo narod koji nas ne može spasiti."},{"v":18,"t":"Vrebaju nam na korake da ne hodamo po trgovima svojim. Bliži nam se kraj, navršili nam se dani, naš konac dolazi."},{"v":19,"t":"Naši gonitelji bijahu brži od orlova na nebu; u planini nas ganjahu, u pustinji dočekivahu u zasjedi."},{"v":20,"t":"Naš životni dah, Jahvin pomazanik, pade u njihove jame - on za koga govorasmo: “U sjeni njegovoj živjet ćemo među narodima.”"},{"v":21,"t":"Raduj se i veseli se, Kćeri edomska, ti koja živiš u zemlji Usu: doći će i do tebe čaša, opit ćeš se i razgoliti."},{"v":22,"t":"Tvoj grijeh je iskupljen, Kćeri sionska, neće te više u izgnanstvo voditi. Kaznit će opačinu tvoju, Kćeri edomska, razotkriti grijehe tvoje."}]},"5":{"hr":[{"v":1,"t":"Spomeni se, Jahve, što nas je snašlo, pogledaj, vidi sramotu našu!"},{"v":2,"t":"Baština naša pade u ruke strancima, domovi naši pripadoše tuđincima."},{"v":3,"t":"Siročad smo: oca nemamo, majke su nam kao udovice."},{"v":4,"t":"Vodu što pijemo plaćamo novcem, i za drvo valja nam platiti."},{"v":5,"t":"Jaram nam je o vratu, gone nas, iscrpljeni smo, ne daju nam predahnuti."},{"v":6,"t":"Pružamo ruke k Egiptu i Asiriji da se kruha nasitimo."},{"v":7,"t":"Oci naši zgriješiše i više ih nema, a mi nosimo krivice njihove."},{"v":8,"t":"Robovi nama zapovijedaju, a nitko da nas izbavi iz ruku njihovih."},{"v":9,"t":"Kruh svoj donosimo izlažući život maču u pustinji."},{"v":10,"t":"Koža nam gori kao peć užarena, ognjicom od plamena gladi."},{"v":11,"t":"Oskvrnuli su žene na Sionu i djevice u gradovima judejskim."},{"v":12,"t":"Svojim su rukama vješali knezove, ni lica staračka nisu poštivali."},{"v":13,"t":"Mladići su nosili žrvnjeve, djeca padala pod bremenom drva."},{"v":14,"t":"Starci su ostavili vrata, mladići više ne sviraju na lirama."},{"v":15,"t":"Radosti nesta iz naših srdaca, naš ples se pretvori u tugovanje."},{"v":16,"t":"Pao je vijenac s naše glave, jao nama što zgriješismo!"},{"v":17,"t":"Evo zašto nam srce boluje, evo zašto nam oči se zastiru:"},{"v":18,"t":"zato što Gora sionska opustje i po njoj se šuljaju šakali."},{"v":19,"t":"Ali ti, Jahve, ostaješ zauvijek, tvoj je prijesto od koljena do koljena."},{"v":20,"t":"Zašto da nas zaboraviš zauvijek, da nas ostaviš za mnoge dane?"},{"v":21,"t":"Vrati nas k sebi, Jahve, obratit ćemo se, obnovi dane naše kao što nekoć bijahu."},{"v":22,"t":"Il' nas hoćeš sasvim zabaciti i na nas se beskrajno srditi?"}]}},"EZK":{"1":{"hr":[{"v":1,"t":"Godine tridesete, četvrtoga mjeseca, petoga dana, kad bijah među izgnanicima na rijeci Kebaru, otvoriše se nebesa i ja ugledah božanska viđenja."},{"v":2,"t":"Petoga dana istoga mjeseca - godine pete otkako odvedoše u izgnanstvo kralja Jojakima -"},{"v":3,"t":"riječ Jahvina dođe Ezekielu, sinu Buzijevu, svećeniku u zemlji kaldejskoj, na rijeci Kebaru. Spusti se na me ruka Jahvina."},{"v":4,"t":"Pogledah, kad ono sa sjevera udario silan vihor, velik oblak, bukteći oganj obavijen sjajem; usred njega, usred ognja, nešto nalik na sjajnu kovinu."},{"v":5,"t":"Usred toga nešto kao četiri bića, obličjem slična čovjeku;"},{"v":6,"t":"svako od njih sa četiri obraza, u svakoga četiri krila."},{"v":7,"t":"Noge im ravne, a stopala kao u teleta; sijevahu poput glatke mjedi."},{"v":8,"t":"Ispod krila imahu na sve četiri strane ruke čovječje. I svako od njih četvero imaše svoj obraz i svoja krila."},{"v":9,"t":"Krila im se spajahu jedno s drugim. Idući, ne okretahu se: svako se naprijed kretaše."},{"v":10,"t":"I u sva četiri bijaše lice čovječje; u sva četiri zdesna lice lavlje; u sva četiri slijeva lice volujsko; i lice orlovsko u sva četiri."},{"v":11,"t":"Krila im bijahu gore raskriljena. Svako imaše dva krila što se spajahu i dva krila kojim tijelo pokrivahu."},{"v":12,"t":"I svako iđaše samo naprijed. A iđahu onamo kamo ih je duh gonio. I ne okretahu se idući."},{"v":13,"t":"A posred tih bića vidjelo se kao neko užareno ugljevlje, kao goruće zublje koje se među njima kretahu; iz ognja sijevaše i munje bljeskahu."},{"v":14,"t":"Bića trčahu i opet se vraćahu poput munje."},{"v":15,"t":"Dok ja promatrah, gle: na zemlji uza svako od četiri bića po jedan točak."},{"v":16,"t":"Točkovi bijahu slični krizolitu, sva četiri istoga oblika; oblikom i napravom bijahu kao da je jedan točak u drugome."},{"v":17,"t":"U kretanju mogli su ići u sva četiri smjera a nisu se morali okretati."},{"v":18,"t":"Naplatnice im bijahu visoke, a kad bolje promotrih, gle, na sve strane pune očiju."},{"v":19,"t":"Kad bi bića krenula, krenuli bi s njima i točkovi; kad bi se bića sa tla podigla, i točkovi se podizahu."},{"v":20,"t":"Kuda ih je duh gonio, onuda se kretahu, a zajedno se s njima i točkovi podizali, jer duh bića bijaše u točkovima."},{"v":21,"t":"Pa kad su bića krenula, i točkovi bi krenuli, a kad bi se ona zaustavila, ustavljali se i točkovi; kad se ona sa tla dizahu, i točkovi se s njima podizahu, jer duh bića bijaše u točkovima."},{"v":22,"t":"Nad glavama bića bijaše nešto kao svod nebeski, nalik na sjajan prozirac, uzdignut nad njihovim glavama."},{"v":23,"t":"A pod svodom raskriljena krila, jedno prema drugome: svakome po dva krila pokrivahu tijelo."},{"v":24,"t":"Čuh lepet njihovih krila kao huk velikih voda, kao glas Svesilnog, kao silan vihor, kao graju u taboru. Kad bi se bića zaustavila, spustila bi krila."},{"v":25,"t":"Sa svoda nad njihovim glavama čula se grmljavina."},{"v":26,"t":"Ispod svoda nad njihovim glavama bijaše nešto kao kamen safir, poput prijestolja: na tom kao prijestolju, gore na njemu, kao neki čovjek."},{"v":27,"t":"I vidjeh kao sjajnu kovinu, iznutra i uokolo kao oganj; od njegovih bokova naviše i od njegovih bokova naniže nešto poput ognja i blijeska na sve strane."},{"v":28,"t":"Taj blijesak na sve strane bijaše poput duge što se za kišnih dana javlja u oblaku. To bijaše nešto kao slava Jahvina. Vidjeh, padoh ničice i čuh glas koji mi govoraše."}]},"2":{"hr":[{"v":1,"t":"I reče mi: “Sine čovječji, na noge se, da s tobom govorim!”"},{"v":2,"t":"OI uđe u me duh, kako mi progovori, te me podiže na noge i ja čuh glas onoga koji mi govoraše."},{"v":3,"t":"I reče mi: “Sine čovječji, šaljem te k sinovima Izraelovim, k narodu odmetničkom što se odvrže od mene. Oni i oci njihovi griješili su protiv mene sve do dana današnjega."},{"v":4,"t":"Šaljem te k sinovima tvrdokorna pogleda i okorjela srca. Reci im: Ovako govori Jahve Gospod!"},{"v":5,"t":"I poslušali oni ili ne poslušali - rod su odmetnički - neka znaju da je prorok među vama."},{"v":6,"t":"A ti, sine čovječji, ne boj ih se i ne plaši se riječi njihovih: 'Trnje te okružuje i sjediš među samim skorpijama.' Ne plaši se riječi njihovih i ne boj se nimalo njihova pogleda jer oni su rod odmetnički."},{"v":7,"t":"Govori im moje riječi, poslušali oni ili ne poslušali, jer rod su odmetnički."},{"v":8,"t":"A ti, sine čovječji, poslušaj što ću ti sada reći: Ne budi odmetnik kao što su oni rod odmetnički! Otvori usta i progutaj što ću ti sada dati!”"},{"v":9,"t":"I pogledah, a to ruka k meni ispružena i u njoj, gle, svitak knjige."},{"v":10,"t":"I razvi se knjiga preda mnom: bijaše ispisana izvana i iznutra, a u njoj napisano: “Naricanje! Jecanje! Jauk!”"}]},"3":{"hr":[{"v":1,"t":"I reče mi: “Sine čovječji, progutaj što je pred tobom! Pojedi taj svitak, te idi i propovijedaj domu Izraelovu!”"},{"v":2,"t":"Otvorih usta, a on mi dade da progutam svitak"},{"v":3,"t":"i reče: “Sine čovječji, nahrani trbuh i nasiti utrobu svitkom što ti ga dajem!” I pojedoh ga, i bijaše mi u ustima sladak kao med."},{"v":4,"t":"Reče mi: “Sine čovječji, idi domu Izraelovu i prenesi mu moju poruku."},{"v":5,"t":"Ne šaljem te k narodu nepoznata jezika i nerazumljiva govora, već te šaljem domu Izraelovu."},{"v":6,"t":"Ne šaljem te k mnogim narodima nepoznata jezika i nerazumljiva govora koje ti ne bi mogao razumjeti. A kad bih te k njima i poslao, oni bi te poslušali."},{"v":7,"t":"A dom te Izraelov neće poslušati, jer ni mene ne sluša, jer dom je Izraelov tvrde glave i okorjela srca."},{"v":8,"t":"Evo, zato ću sada otvrdnuti tvoje lice kao što je i njihovo i glavu ću tvoju učiniti tvrdoglavom kao što je njihova."},{"v":9,"t":"I ne boj ih se i ne plaši, jer oni su rod odmetnički!”"},{"v":10,"t":"Reče mi: “Sine čovječji, sve riječi što ću ti reći uzmi k srcu i poslušaj ih svojim ušima."},{"v":11,"t":"I hajde izgnanicima, sinovima svojega naroda, i reci im: Ovako govori Jahve Gospod! - poslušali ili ne poslušali!”"},{"v":12,"t":"Uto me duh podiže i ja za sobom čuh silnu tutnjavu. Slava se Jahvina podigla sa svojega mjesta."},{"v":13,"t":"Čuh lepet krila onih bića - udarahu jedno o drugo - i snažnu škripu točkova što se s njima kretahu i zaglušnu jeku jakoga glasa."},{"v":14,"t":"Tada me duh prihvati i ponese. I ja iđah ogorčen i gnjevna srca, a ruka me Jahvina čvrsto pritisla."},{"v":15,"t":"Tako stigoh u Tel Abib, k izgnanicima koji življahu na rijeci Kebaru - onamo gdje se bijahu nastanili - te ostadoh među njima sedam dana kao omamljen."},{"v":16,"t":"Poslije sedam dana dođe mi opet riječ Jahvina:"},{"v":17,"t":"“Sine čovječji, postavljam te za čuvara doma Izraelova. I ti ćeš riječi iz mojih usta slušati i opominjat ćeš ih u moje ime."},{"v":18,"t":"Kad bezbožniku reknem: 'Umrijet ćeš', a ti ga ne opomeneš i ne odvratiš od zla puta njegova kako bi mu život spasio, on će umrijeti sa svojega bezakonja, ali ću ja od tebe tražiti račun za krv njegovu."},{"v":19,"t":"A kad opomeneš bezbožnika, a on se ne odvrati od bezakonja i od zla puta svojega, on će umrijeti zbog svoje krivice, a ti ćeš spasiti svoj život."},{"v":20,"t":"Isto tako, odvrati li se pravednik od svoje pravednosti i stane činiti nepravdu, postavit ću mu zamku i umrijet će jer ga ti ne opomenu zbog njegova grijeha; umrijet će, i njegova se pravedna djela više neće spominjati, ali ću od tebe tražiti račun za krv njegovu."},{"v":21,"t":"Ako li ti pravednika opomeneš da ne griješi, i on zaista prestane griješiti, živjet će jer je prihvatio opomenu, a i ti ćeš spasiti život svoj.”"},{"v":22,"t":"Ondje me opet zahvati ruka Jahvina i on mi reče: “Ustani i siđi u dolinu da ondje s tobom govorim!”"},{"v":23,"t":"Ustadoh tada i siđoh u dolinu, i gle: Slava Jahvina stajaše ondje, slična Slavi koju vidjeh na rijeci Kebaru te padoh ničice."},{"v":24,"t":"Jahvin duh uđe u me, osovi me na noge i reče: “Idi i zatvori se u domu svojemu!"},{"v":25,"t":"Na te ću, evo, sine čovječji, staviti užad i svezati te i više nećeš izlaziti."},{"v":26,"t":"I jezik ću ti zalijepiti za nepce te ćeš onijemjeti i nećeš ih više karati, jer su rod odmetnički."},{"v":27,"t":"A kad ti ja progovorim, otvorit ću ti usta i ti ćeš im reći: Ovako govori Jahve Gospod! I tko hoće slušati, neka sluša, a tko neće, neka ne sluša, jer su rod odmetnički."}]},"4":{"hr":[{"v":1,"t":"A ti, sine čovječji, uzmi opeku, postavi je preda se i nacrtaj na njoj grad Jeruzalem."},{"v":2,"t":"Oko njega postavi opsadu, sagradi prema njemu utvrdu, podigni nasip, iskopaj oko njega opkop, razvrstaj vojsku i porazmjesti zidodere uokolo."},{"v":3,"t":"Zatim uzmi gvozdenu ploču i postavi je kao gvozden bedem između sebe i grada te k njemu okreni lice, i bit će opsjednut. Pritisni ga! To je znak domu Izraelovu!"},{"v":4,"t":"Zatim lezi na svoju lijevu stranu i stavi na se grijeh doma Izraelova: koliko dana budeš tako ležao, toliko ćeš dana nositi njihov grijeh."},{"v":5,"t":"Dajem ti po dan za godine grijeha njihovih: sto i devedeset dana nosit ćeš grijeh doma Izraelova."},{"v":6,"t":"A kad to završiš, četrdeset ćeš dana ležati na desnoj strani da nosiš grijeh doma Judina; dajem ti po dan za svaku godinu."},{"v":7,"t":"Tad okreni lice prema opsjedanom Jeruzalemu, pruži golu desnicu i prorokuj protiv njega."},{"v":8,"t":"A ja ću te užetima vezati da se ne možeš okretati s jedne strane na drugu dok ne navršiš dane svoje opsade."},{"v":9,"t":"Uzmi pšenice, ječma, boba, leće, prosa i raži, stavi to u jednu posudu i pripravi od toga sebi kruh. Jest ćeš ga onoliko dana koliko budeš ležao na svojoj strani: sto i devedeset dana."},{"v":10,"t":"Jelo što ćeš ga jesti bit će izmjereno; dvadeset šekela na dan; a jest ćeš ga u određeno vrijeme."},{"v":11,"t":"I vodu ćeš piti na mjeru: šestinu hina. Pit ćeš je u određeno vrijeme."},{"v":12,"t":"A jest ćeš pogaču od ječma što ćeš je pred njima ispeći na ljudskim izmetinama.”"},{"v":13,"t":"I reče: “Tako će sinovi Izraelovi jesti svoj nečisti kruh među narodima među koje ću ih izagnati.”"},{"v":14,"t":"Ja mu odgovorih: “Jao, Jahve Gospode, gle, moja duša nije okaljana, jer se od djetinjstva još ne okusih ničega uginulog ni rastrganog niti u moja usta ikad uđe meso nečisto.”"},{"v":15,"t":"A on će: “Gle, dajem ti kravlju balegu umjesto ljudskih izmetina da na njoj ispečeš kruh!”"},{"v":16,"t":"Još mi reče: “Sine čovječji, uništit ću u Jeruzalemu posljednju pričuvu kruha, i jest će kruh na mjeru i s tjeskobom, i pit će vodu na mjeru i sa zebnjom."},{"v":17,"t":"Neka im nestane kruha i vode, neka usahnu zbog bezakonja svojega i jedan za drugim neka poginu!"}]},"5":{"hr":[{"v":1,"t":"A ti, sine čovječji, uzmi mač naoštren, uzmi ga kao britvu brijačku i obrij glavu i bradu. Zatim uzmi mjerice i porazdijeli."},{"v":2,"t":"Trećinu spali posred grada ognjem kad se navrše dani tvoje opsade; trećinu uzmi i sasijeci mačem oko grada; trećinu baci u vjetar - i svoj ću mač trgnuti na njih."},{"v":3,"t":"Uzmi malo i zaveži u skute haljine."},{"v":4,"t":"Od toga opet nešto uzmi, baci u vatru i spali: odatle će se razgorjeti vatra svemu domu Izraelovu!”"},{"v":5,"t":"Ovako govori Jahve Gospod: “Ovo je Jeruzalem! Postavih ga u središte naroda, okružih ga zemljama!"},{"v":6,"t":"Ali se on odupro mojim naredbama većma nego pogani, zakonima mojim većma nego zemlje koje ga okružuju.”"},{"v":7,"t":"Stoga ovako govori Jahve Gospod: “Buntovniji ste od naroda koji vas okružuju, ne hodite po mojim zakonima i ne vršite ni mojih naredaba ni naredaba okolnih naroda.”"},{"v":8,"t":"Zato ovako govori Jahve Gospod: “Evo i mene protiv tebe! Izvršit ću sud svoj nad tobom na oči svih naroda."},{"v":9,"t":"Zbog tvojih gadosti učinit ću s tobom što još ne učinih nikada nit ću ikad učiniti:"},{"v":10,"t":"posred tebe očevi će jesti sinove, a sinovi očeve; izvršit ću sud svoj nad tobom i sav ostatak tvoj predati svim vjetrovima!"},{"v":11,"t":"Života mi moga! - riječ je Jahve Gospoda - svakojakim grozotama i gadostima ti uistinu oskvrnu moje Svetište. I ja ću sada brijati i oko se moje neće sažaliti i neću se smilovati:"},{"v":12,"t":"trećina će tvojih žitelja posred tebe od kuge skončati i od gladi umrijeti; trećina će oko tebe od mača pasti; trećinu ću predati vjetrovima - i mač ću svoj trgnuti na njih!"},{"v":13,"t":"Tako ću iskaliti gnjev svoj i smirit će se jarost moja kad im se osvetim. I kad iskalim jarost svoju nad njima, spoznat će da sam to ja, Jahve, u ljubomori svojoj bio rekao."},{"v":14,"t":"Opustošit ću te, izvrgnut ću te ruglu naroda koji te okružuju, na oči svim prolaznicima."},{"v":15,"t":"Da, bit ćeš na ruglo i sramotu, opomena i užas okolnim narodima kad izvršim protiv tebe sve svoje sudove kažnjavajući gnjevno, jarosno. Ja, Jahve, rekoh!"},{"v":16,"t":"I kad na vas pustim ljute strijele gladi što zatiru, koje ću pustiti na vas da vas uništim i glađu zatrem - uništit ću vam i posljednju pričuvu kruha."},{"v":17,"t":"A povrh gladi pustit ću na vas i divlje zvijeri koje će ti djecu rastrgati; kuga će te i krv preplaviti: pod mač ću te svoj okrenuti. Ja, Jahve, rekoh!”"}]},"6":{"hr":[{"v":1,"t":"Tada mi dođe riječ Jahvina i reče:"},{"v":2,"t":"“Sine čovječji, okreni lice prema gorama Izraelovim i prorokuj protiv njih."},{"v":3,"t":"Reci: 'Gore Izraelove, čujte riječ Jahve Gospoda! Ovako govori Jahve Gospod: Gore i brežuljci, jaruge i doline, evo, spustit ću mač na vas i oborit ću uzvišice vaše!"},{"v":4,"t":"Opustjet će žrtvenici vaši i porušit će se stupovi vaši, a vaše poginule pred kumire ću vam baciti."},{"v":5,"t":"Pobacat ću trupla sinova Izraelovih pred kumire njihove i rasijat ću kosti vaše oko žrtvenika vaših!"},{"v":6,"t":"Gdje god boravili, gradovi će vaši biti opustošeni, uzvišice poharane, žrtvenici će vam opustjeti i biti uništeni, kumiri će vaši biti oboreni i nestat će ih, stupovi će vaši biti smrvljeni, sva će djela vaša propasti."},{"v":7,"t":"Među vas će padati poginuli, i znat ćete da sam ja Jahve!"},{"v":8,"t":"Ali ću ipak poštedjeti neke od vas: ti će među narodima uteći maču kad se raspršite po zemljama."},{"v":9,"t":"Tada će se preživjeli među vama spomenuti mene među narodima kamo budu odvedeni u izgnanstvo, kad im slomim srce preljubničko što se odmetnulo od mene i kad im iskopam preljubničke oči što pođoše za kumirima njihovim. I tada će sami sebi omrznuti zbog nedjela što ih počiniše gadostima svojim."},{"v":10,"t":"I spoznat će da sam ja Jahve: nisam im zaludu govorio da ću ih udariti svim tim zlom.'”"},{"v":11,"t":"Ovako govori Jahve Gospod: “Pljesni rukama i lupni nogama, te reci: Jao! zbog svih gadnih nedjela dom će Izraelov pasti od mača, gladi i kuge!"},{"v":12,"t":"Tko bude daleko, od kuge će umrijeti; tko bude blizu, od mača će pasti, i tko bude opkoljen, od gladi će izdahnuti! Tako ću gnjev iskaliti na njima"},{"v":13,"t":"i spoznat će da sam ja Jahve kad im poginuli budu ležali među kumirima oko žrtvenika na svakome povišem brežuljku, nad svim vrhovima planinskim, pod svakim stablom zelenim, pod svakim hrastom granatim, gdje se god prinosio ugodan miris kumirima njihovim."},{"v":14,"t":"Ruku ću podići na njih i svu ću im zemlju pretvoriti u pustoš, od pustinje do Rible, posvuda gdje borave! I spoznat će da sam ja Jahve!”"}]},"7":{"hr":[{"v":1,"t":"Opet mi dođe riječ Jahvina i reče:"},{"v":2,"t":"“Ti, sine čovječji, reci: Ovako govori Jahve Gospod zemlji Izraelovoj: 'Primiče se kraj: bliži se konac zemlji na sve četiri strane svijeta!"},{"v":3,"t":"Sada je i tebi kraj: gnjev ću svoj na te izliti, sudit ću ti prema putovima tvojim i na te ću oboriti sve gadosti tvoje!"},{"v":4,"t":"I moje te oči neće požaliti, neću ti se smilovati, nego ću te nagraditi prema putovima tvojim, tvoje će gadosti u tebi ostati. I znat ćete da sam ja Jahve.'”"},{"v":5,"t":"Ovako govori Jahve: “Jedna nesreća, evo, dolazi!"},{"v":6,"t":"Kraj dolazi, dolazi ti kraj, evo, dolazi!"},{"v":7,"t":"Kolo ti udesa dolazi, stanovniče zemlje! Dolazi tvoj čas, bliži se dan: strava je, a ne radost u gorama."},{"v":8,"t":"Eto, uskoro ću na te izliti gnjev i iskalit ću na tebi srdžbu svoju! Sudit ću ti prema putovima tvojim i oborit ću na te sve gadosti tvoje."},{"v":9,"t":"I moje te oči neće požaliti, neću ti se smilovati, nego ću ti platiti prema putovima tvojim i tvoje će gadosti u tebi ostati! I spoznat ćete da sam ja Jahve koji bije."},{"v":10,"t":"Evo, evo dolazi, kolo ti udesa dolazi, prut već cvjeta i oholost pupa,"},{"v":11,"t":"a nasilje se podiže kao žezlo bezbožnosti! I nitko neće ostati od njih, nitko od njihova mnoštva. Ništa od njihove buke, nema u njima vrijednosti."},{"v":12,"t":"Ide vrijeme, bliži se dan! Tko kupuje, neka se ne raduje, a tko prodaje, neka ne tuguje, jer se gnjev izlijeva na sve bogatstvo njegovo."},{"v":13,"t":"Jer tko proda, neće više dobiti što je prodao, i nitko neće bezakonjem ojačati život!"},{"v":14,"t":"Trube trublje i sve je spremno, ali nitko ne kreće u boj, jer gnjev se moj izlijeva na sve bučno mnoštvo."},{"v":15,"t":"Vani - mač, a unutra - kuga i glad! I tko je u polju, od mača će poginuti, a tko u gradu, glad će ga i kuga uništiti."},{"v":16,"t":"Koji uteku, sklonit će se u gore kao dolinski golubovi, a ja ću ih sve istrijebiti, svakoga zbog bezakonja njegova,"},{"v":17,"t":"i sve će ruke klonuti, a koljena će svima malaksati."},{"v":18,"t":"U kostrijet će se odjenuti, trepet će ih obuzeti, sva će lica sramota pokriti, sve će im glave oćelavjeti!"},{"v":19,"t":"Srebro svoje pobacat će na ulice, a zlato će smatrati izmetom: u dan srdžbe Jahvine ni srebro ni zlato neće ih izbaviti, duše im neće moći nasititi ni trbuha napuniti, jer se o to spotakoše na grijeh."},{"v":20,"t":"Uzoholiše se zbog divnoga nakita svojega; od njega napraviše kumire - grozote i gadosti svoje: zato im ga pretvorih u izmet."},{"v":21,"t":"Dat ću ga u ruke tuđincima da oplijene, razgrabe i oskvrnu."},{"v":22,"t":"Odvratit ću od njih lice svoje: i neka se samo oskvrnjuje moja dragocjenost, neka u nju uđu provalnici i neka je oskvrnu!"},{"v":23,"t":"Spremaj lance, jer je zemlja puna krvi i zločina koji zaslužuju smrt i grad prepun nasilja!"},{"v":24,"t":"Zato ću dovesti najgore narode da baštine njihove domove. Slomit ću oholost nasilnika, i svetišta njihova bit će oskvrnjena."},{"v":25,"t":"Dolazi tjeskoba! Tražit će mir, a mira biti neće!"},{"v":26,"t":"Dolazit će nevolja za nevoljom, jedna zla vijest za drugom! I tražit će se viđenje u proroka; u svećenika neće više biti Zakona ni u starješina savjeta!"},{"v":27,"t":"Kralj će protužiti, a kneza će spopasti užas i ruke će puku zadrhtati, jer ću ih nagraditi prema putovima njihovim i sudit ću im prema sudovima njihovim. I znat će da sam ja Jahve.”"}]},"8":{"hr":[{"v":1,"t":"Godine šeste, šestoga mjeseca, petoga dana, dok sjeđah u svojoj kući, a preda mnom starješine judejske, spusti se na me ruka Jahvina."},{"v":2,"t":"Pogledah, i gle: tu kao neki čovjek; od njegovih kao bokova naniže oganj, a od njegovih kao bokova naviše bljeskanje, nešto poput usijane kovine."},{"v":3,"t":"Ispruži nešto nalik na ruku i uhvati me za kosu na glavi. Uto me duh podiže između zemlje i neba i ponese me u božanskome viđenju u Jeruzalem, na ulaz unutrašnjih vrata, što su okrenuta prema sjeveru gdje stoji kumir, ljubomora koja izaziva ljubomoru."},{"v":4,"t":"I gle, ondje bijaše Slava Boga Izraelova, kao što je vidjeh u dolini."},{"v":5,"t":"I reče mi: “Sine čovječji, podigni oči prema sjeveru!” I podigoh oči prema sjeveru. I gle, kumir, ljubomora, bijaše i na sjeveru, kraj vrata žrtvenika, na strani prema ulazu."},{"v":6,"t":"I reče mi: “Sine čovječji, vidiš li što oni ovdje čine? Velike su to gnusobe što ih dom Izraelov ovdje čini, samo da me udalji iz mojega Svetišta. A vidjet ćeš i gorih gnusoba!”"},{"v":7,"t":"I povede me do vrata predvorja. Pogledah, i gle: u zidu pukotina."},{"v":8,"t":"I reče mi: “Sine čovječji, probij taj zid!” Probih zid, a ono - ulaz!"},{"v":9,"t":"I reče mi: “Uđi i pogledaj strahovite gadosti što se ovdje čine!”"},{"v":10,"t":"Uđoh i pogledah. I gle, svakojake slike gmazova i gnusnih životinja - sve kumiri doma Izraelova, našarani na zidu, svuda uokolo."},{"v":11,"t":"A pred tim kumirima sedamdesetorica ljudi od starješina doma Izraelova, i među njima i Šafanov sin Jaazanija. I svakome od njih u ruci kadionica iz koje se podiže oblak kada miomirisnoga."},{"v":12,"t":"I reče mi: “Sine čovječji, vidiš li što u toj tami rade starješine doma Izraelova, svatko u svojoj oslikanoj komori? I još govore: Jahve nas ne vidi jer je Jahve napustio zemlju!”"},{"v":13,"t":"I reče mi još: “A vidjet ćeš i gorih gnusoba što se ovdje čine!”"},{"v":14,"t":"I povede me do vrata Doma Jahvina što su okrenuta prema sjeveru. I gle, ondje sjeđahu žene i oplakivahu Tamuza."},{"v":15,"t":"I reče mi: “Vidiš li, sine čovječji? A vidjet ćeš i gorih gnusoba od ovih!”"},{"v":16,"t":"I povede me u unutrašnje predvorje Doma Jahvina. Ondje, na ulazu u Hekal Jahvin, između trijema i žrtvenika, bijaše oko dvadeset i pet ljudi, okrenutih leđima Hekalu Jahvinu, a licem prema istoku, i ondje se prema istoku klanjahu suncu."},{"v":17,"t":"I reče mi: “Vidiš li to, sine čovječji? Malo li je domu Judinu svih ovih gnusoba što ih ovdje čine, nego mi još zemlju pune i nasiljem, i ponovo me izazivaju i granama pred nosom mašu?"},{"v":18,"t":"Zato ću i ja sada postupiti s njima jarosno i oči se moje više neće sažaliti i neću im se smilovati. I kad stanu iza glasa vikati na moje uši, neću ih uslišiti.”"}]},"9":{"hr":[{"v":1,"t":"Tada zagrmje na moje uši i reče: “Kazne grada! Priđite svaka sa svojim zatornim oružjem u ruci!”"},{"v":2,"t":"I gle, dođoše šestorica ljudi s gornjih vrata, što su okrenuta k sjeveru, svaki sa svojim zatornim oružjem u ruci. Među njima bijaše i jedan odjeven u lan, s pisarskim priborom za pojasom. Uđoše oni i stadoše uz tučani žrtvenik."},{"v":3,"t":"A Slava Boga Izraelova vinu se s kerubina, nad kojima lebdijaše, prema pragu Doma. I pozva čovjeka odjevena u lan, koji imaše za pojasom pisarski pribor,"},{"v":4,"t":"te mu reče: “Prođi gradom Jeruzalemom i znakom 'tau' obilježi čela sviju koji tuguju i plaču zbog gnusoba što se u njemu čine!”"},{"v":5,"t":"A drugima reče na moje uši: “Pođite za njim gradom i ubijajte bez milosrđa. Oči vaše neka se ne sažale i nemajte smilovanja."},{"v":6,"t":"Pobijte starce, mladiće, djevojke, djecu i žene; istrijebite ih sve do posljednjega. Ali na kome bude znak 'tau', njega ne dirajte. Počnite od mojega Svetišta!” I oni počeše od starješina koji stajahu pred Domom."},{"v":7,"t":"I reče im: “Oskvrnite Dom moj i napunite mu predvorje truplima! Krenite!” I oni iziđoše te zaredaše ubijati gradom."},{"v":8,"t":"Dok su oni klali, ja ostadoh, bacih se ničice i zavapih: “Jao, Jahve Gospode! Zar ćeš zaista uništiti sve što preostade od Izraela da iskališ svoj gnjev nad Jeruzalemom?”"},{"v":9,"t":"Reče mi: “Veoma je veliko bezakonje doma Izraelova i doma Judina; zemlja je puna krvi, a grad krcat zločina. Govore: 'Jahve je ostavio zemlju! Ne vidi Jahve!'"},{"v":10,"t":"I zato se moje oči neće sažaliti i neću im se smilovati: djela ću im njihova oboriti na glavu!”"},{"v":11,"t":"I gle, čovjek odjeven u lan, koji imaše za pojasom pisarski pribor, javi vijesti: “Učinih kako si mi zapovjedio!”"}]},"10":{"hr":[{"v":1,"t":"Pogledah, i gle: na svodu nad glavama kreubinÄa pojavi se nešto kao kamen safir, kao nekakvo prijestolje."},{"v":2,"t":"I prozbori čovjeku odjevenom u lan: “Uđi među točkove pod kerubinima, uzmi pune pregršti žeravice između kerubina i prospi je nad gradom!” - I on na moje oči uđe među kerubine."},{"v":3,"t":"A kerubini stajahu s desne strane Doma kad čovjek uđe među njih. I oblak ispuni sve unutrašnje predvorje,"},{"v":4,"t":"a Slava Jahvina vinu se s kerubinÄa prema pragu Doma. Dom se ispuni oblakom, a predvorje napuni svjetlost Slave Jahvine."},{"v":5,"t":"Huka kerubinskih krila razliježe se do vanjskoga predvorja, kao kad zagrmi glas Svevišnjega."},{"v":6,"t":"A kad on zapovjedi čovjeku odjevenom u lan: “Uzmi ognja između točkova što su pod kerubinima”, čovjek uđe i stade kraj točkova."},{"v":7,"t":"Jedan kerubin pruži ruku prema ognju što bijaše među kerubinima, uze ga i stavi u ruke čovjeku odjevenom u lan. On ga primi i iziđe."},{"v":8,"t":"A ispod kerubinskih krila ukaza se nešto kao ruka čovječja."},{"v":9,"t":"Pogledah, i gle: uz kerubine četiri točka, po jedan uza svakoga. A točkovi bijahu nalik na kamen krizolit;"},{"v":10,"t":"sva četiri istog oblika i kao da je jedan točak u drugome."},{"v":11,"t":"U kretanju mogahu ići u sva četiri smjera, sve bez zakretanja. Kamo bi se glava usmjerila, onamo bi krenuli, a da se, krećući se, nisu morali okretati."},{"v":12,"t":"Cijelo tijelo u kerubinÄa - leđa, ruke, krila i sva četiri točka njihova - sve im bijaše posvud naokolo puno očiju."},{"v":13,"t":"A točkovi, koliko sam čuo, zvahu se “Kovitlac”."},{"v":14,"t":"Svaki imaše po četiri lica: lice prvoga kerubinsko, lice drugoga čovječje, a u trećega lice lavlje, u četvrtoga orlovsko."},{"v":15,"t":"Tada se kerubini podigoše u visine. Bijahu to ista bića što ih vidjeh na rijeci Kebaru."},{"v":16,"t":"Kad bi kerubini krenuli, krenuli bi i točkovi uz njih, kad bi kerubini krilima mahnuli da se od zemlje podignu, točkovi se ne bi od njih odmicali."},{"v":17,"t":"Kad bi se zaustavili, i točkovi bi stali; a kad bi se sa zemlje podigli, i točkovi se podizahu, jer duh bića bijaše u njima."},{"v":18,"t":"Uto se Slava Jahvina vinu s praga Doma i stade nad kerubinima."},{"v":19,"t":"Tada kerubini raširiše krila i podigoše se sa zemlje pred mojim očima. A kad oni krenuše, i točkovi za njima krenuše. I zaustaviše se nad istočnim vratima Doma Jahvina, a Slava Boga Izraelova bijaše nad njima."},{"v":20,"t":"Bijahu to ista bića što ih vidjeh pred Bogom Izraelovim na rijeci Kebaru. I tako spoznah da ono bijahu kerubini."},{"v":21,"t":"U svakoga po četiri lica i po četiri krila, a pod krilima nešto kao ruka čovječja."},{"v":22,"t":"Lica im ista kao ona što ih vidjeh na rijeci Kebaru. I svako se naprijed kretaše."}]},"11":{"hr":[{"v":1,"t":"Tada se duh podiže i ponese me do istočnih vrata Doma Jahvina, što su okrenuta k istoku. I gle: na ulazu vrata dvadeset i pet ljudi, među kojima vidjeh i Jaazaniju, sina Azurova, i Pelatju, sina Benajina, knezove narodne."},{"v":2,"t":"I reče mi: “Sine čovječji, evo ljudi koji smišljaju opačine i koji u ovom gradu daju zle savjete:"},{"v":3,"t":"'Nije li čas da gradimo domove? Ovaj je grad kotao, a mi smo meso.'"},{"v":4,"t":"Zato prorokuj protiv njih, prorokuj, sine čovječji!”"},{"v":5,"t":"I duh Jahvin siđe nada me i kaza mi: “Reci: Ovako veli Jahve Gospod: 'Ne govoriš li tako, dome Izraelov? Ali ja poznajem misli vašega srca!"},{"v":6,"t":"Množite ubojstva u ovome gradu i njegove ulice punite truplima.'"},{"v":7,"t":"Zato ovako govori Jahve Gospod: 'Oni koje vi probodoste i razbacaste po gradu - oni su meso, a grad je kotao. Zato ću vas ja izvesti sada iz njega."},{"v":8,"t":"Od mača strahujete, i mač ću na vas dovesti - riječ je Jahve Gospoda!"},{"v":9,"t":"Izvest ću vas iz grada i predati vas u ruke tuđincima, i sud ću svoj izvršiti nad vama:"},{"v":10,"t":"od mača ćete pasti! Na međi Izraelovoj sudit ću vam, i tada ćete znati da sam ja Jahve!"},{"v":11,"t":"A ovaj grad više vam neće biti kotao i vi nećete biti meso njegovo. Na međi Izraelovoj sudit ću vam,"},{"v":12,"t":"i tada ćete znati da sam ja Jahve po čijim uredbama ne živjeste i čijih zakona ne izvršavaste, nego živjeste po zakonima okolnih naroda!'”"},{"v":13,"t":"Dok ja tako prorokovah, umrije Pelatja, sin Benajin. I ja padoh ničice te zavapih iz svega glasa: “Jao, Jahve Gospode, zar ćeš doista uništiti sav Ostatak doma Izraelova?”"},{"v":14,"t":"I dođe mi riječ Jahvina:"},{"v":15,"t":"“Sine čovječji, tvojoj braći, i tvojim rođacima, i svem domu Izraelovu Jeruzalemci govore: 'Daleko ste od Jahve! Nama je ova zemlja dana u posjed!'"},{"v":16,"t":"Zato im reci: Ovako govori Jahve Gospod: 'Ako ih i odagnah među daleke narode, ako ih i rasprših po zemljama, ja ću im sam uskoro biti Svetište u zemljama u kojima se nalaze.'"},{"v":17,"t":"Stoga im reci: Ovako govori Jahve Gospod: 'Sabrat ću vas iz narodÄa, vratit ću vas iz zemalja u kojima ste bili raspršeni i dat ću vam opet zemlju Izraelovu!"},{"v":18,"t":"I kad se u nju vrate, istrijebit će iz nje sve grozote i gadosti."},{"v":19,"t":"I ja ću im dati novo srce i nov ću duh udahnuti u njih: iščupat ću iz njih njihovo kameno srce i stavit ću u njih srce od mesa,"},{"v":20,"t":"da hode po mojim naredbama i da čuvaju i vrše sve moje zakone. I bit će oni moj narod, a ja Bog njihov!"},{"v":21,"t":"A onima kojima srce hodi za grozotama i gadostima oborit ću na glavu njihov put' - riječ je Jahve Gospoda.”"},{"v":22,"t":"Kerubini podigoše krila i točkovi se digoše za njima, a Slava Boga Izraelova lebdijaše nad njima."},{"v":23,"t":"Slava se Jahvina vinu iz grada i zaustavi se na gori, istočno od grada."},{"v":24,"t":"A mene duh podiže i ponese duhom Božjim k izgnanicima u zemlju kaldejsku. I iščeznu viđenje koje gledah."},{"v":25,"t":"I pripovjedih izgnanicima sve što mi Jahve bijaše objavio."}]},"12":{"hr":[{"v":1,"t":"Opet mi dođe riječ Jahvina:"},{"v":2,"t":"“Sine čovječji! Ti boraviš u rodu odmetničkom koji ima oči, a ne vidi, uši ima, a ne čuje, jer su rod odmetnički."},{"v":3,"t":"Zato, sine čovječji, spremi izgnanički zavežljaj i njima na oči obdan se seli: seli se iz svojega mjesta u drugo, ne bi li uvidjeli da su rod odmetnički."},{"v":4,"t":"Obdan, njima na oči, iznesi zavežljaj, zavežljaj izgnanički, a iziđi obnoć na njihove oči kao što se odlazi u izgnanstvo."},{"v":5,"t":"Njima na oči prokopaj zid i kroza nj izađi."},{"v":6,"t":"I njima na oči vrgni zavežljaj na ramena i po mrkloj noći iziđi. Pokrij lice da ne vidiš zemlju, jer te postavih kao znamenje domu Izraelovu!”"},{"v":7,"t":"Učinih kako mi bijaše zapovjeđeno: obdan iznesoh zavežljaj, zavežljaj izgnanički, a obnoć prokopah zid rukama i njima na oči po mrkloj noći vrgoh zavežljaj na ramena."},{"v":8,"t":"Ujutro mi dođe riječ Jahvina:"},{"v":9,"t":"“Sine čovječji, zapita li te dom Izraelov, dom odmetnički: 'Što to radiš?'"},{"v":10,"t":"ti mu reci: 'Ovako govori Jahve Gospod! Ovo je proroštvo knezu jeruzalemskom i svemu domu Izraelovu koji je u Jeruzalemu.'"},{"v":11,"t":"Reci: 'Ja sam vam znamenje! Kako ja uradih, tako će biti njima: svi ćete se morati seliti u izgnanstvo!"},{"v":12,"t":"Knez njihov morat će vrći zavežljaj na ramena i po mrkloj noći izaći. Prokopat će zid da izađe kroza nj i lice će pokriti rukama da očima ne vidi zemlje."},{"v":13,"t":"Ja ću mu razapeti mrežu, i uhvatit će se u moju zamku, i odvest ću ga u Babilon, u zemlju kaldejsku. Ali je on neće ugledati i ondje će život ostaviti."},{"v":14,"t":"A sve one oko njega, pomagače i čete, raspršit ću u sve vjetrove i svoj mač ću trgnuti na njih."},{"v":15,"t":"A kad ih raspršim među narode i rasijem po zemljama, znat će da sam ja Jahve."},{"v":16,"t":"Ipak, ostavit ću nekolicinu koji će umaći maču, gladi i kugi, da među narodima kamo prispiju pripovijedaju svoje gadosti; neka se zna da sam ja Jahve.'”"},{"v":17,"t":"I dođe mi riječ Jahvina:"},{"v":18,"t":"“Sine čovječji, jedi kruha zabrinuto i pij vode sa zebnjom i sa strepnjom!"},{"v":19,"t":"I reci puku zemlje: 'Ovako govori Jahve Gospod Jeruzalemcima u zemlji Izraelovoj: Zabrinuto će jesti kruha i sa strepnjom piti vode, jer će im zemlja opustjeti i ostat će bez igdje ičega s bezakonja žitelja svojih."},{"v":20,"t":"I svi gradovi, sada napučeni, bit će poharani, a sva zemlja opustošena. I znat će da sam ja Jahve!'”"},{"v":21,"t":"I dođe mi riječ Jahvina:"},{"v":22,"t":"“Sine čovječji, kakve su vam to priče o zemlji Izraelovoj? Govori se: 'Gle, prolaze dani, a od proroštva ništa!'"},{"v":23,"t":"Zato im reci: Ovako govori Jahve Gospod: 'Dokončat ću te priče i neće se više ponavljati u Izraelu.' Reci im: 'Bliže se već dani i sva će se proroštva moja ispuniti!"},{"v":24,"t":"Jer neće više biti u domu Izraelovu varavih viđenja, ni lažnih proroštava kojima ljude bijahu zavodili."},{"v":25,"t":"Jer što ja, Jahve Gospod, govorim, to će i biti, i riječ se neće odgoditi! Da! Još za vaših dana, rode odmetnički, riječ ću izgovoriti i izvršiti.' Tako govori Jahve Gospod!”"},{"v":26,"t":"I dođe mi riječ Jahvina:"},{"v":27,"t":"“Sine čovječji! Evo što se govori u domu Izraelovu: 'Viđenje što ga ovaj ugleda za dane je daleke! Prorokuje za daleka vremena!'"},{"v":28,"t":"Zato im reci: Ovako govori Jahve Gospod: 'Nijedna riječ moja neće se više odgoditi! Što rekoh, rečeno je, i sve će se ispuniti!' - riječ je Jahve Gospoda.”"}]},"13":{"hr":[{"v":1,"t":"I opet mi dođe riječ Jahvina:"},{"v":2,"t":"“Sine čovječji! Prorokuj protiv onih koji se grade prorocima u Izraelu!"},{"v":3,"t":"Reci tim prorocima koji prorokuju po svojoj glavi: 'Čujte riječ Jahvinu! Ovako govori Jahve Gospod: Jao prorocima bezumnim koji duh svoj slijede a ništa ne vide!"},{"v":4,"t":"Ti su tvoji proroci, Izraele, kao lisice usred ruševina."},{"v":5,"t":"Vi se ne popeste na proboje i ne zidaste zida oko doma Izraelova da se održi u boju u dan Jahvin."},{"v":6,"t":"Viđenja su njihova isprazna, i lažna su njihova proricanja. Govore 'Riječ Jahvina!' - a Jahve ih nije poslao. I još očekuju da će im se riječi ispuniti."},{"v":7,"t":"Zar ne vidite da su vam viđenja isprazna i da su vam lažna proricanja kad govorite 'Riječ Jahvina!' - a ja nisam govorio.'"},{"v":8,"t":"Stoga ovako govori Jahve Gospod: 'Zato što govorite isprazno i laž vidite, evo me protiv vas' - riječ je Jahve Gospoda!"},{"v":9,"t":"Evo, ruka moja bit će protiv proroka koji vide isprazno i laž proriču: neće više biti u zboru mojega naroda, neće biti upisani u knjigu doma Izraelova, nikad više neće stupiti na tlo Izraelovo! I znat će da sam ja Jahve Gospod!"},{"v":10,"t":"Jer narod moj obmanjuju govoreći 'Mir' kad mira nema. I dok jedni hoće da se zid utvrdi, oni hoće da se samo ožbuka."},{"v":11,"t":"Reci onima koji hoće da se samo ožbuka: 'Past će!' Udarit će silan pljusak, oborit ću na nj grÓad kao kamenje, bjesnjet će olujni vihori."},{"v":12,"t":"Evo, zid će pasti! Neće li vas tada pitati: 'Gdje vam je sada žbuka kojom ste ga ožbukali?'"},{"v":13,"t":"Zato ovako govori Jahve Gospod: 'U svojoj jarosti razbjesnit ću olujne vihore, u srdžbi ću svojoj udariti silnim pljuskom da ga zatrem, u gnjevu ću na nj oboriti grÓad kao kamenje."},{"v":14,"t":"Obalit ću zid što ga vi žbukom ožbukaste, na zemlju ću ga oboriti da mu se razgole temelji. Past će zid, i vi ćete pod njim izginuti! Tada ćete znati da sam ja Jahve!"},{"v":15,"t":"Tako ću iskaliti gnjev nad zidom i nad onima koji ga žbukom ožbukaše. A vama ću reći: Nema više zida! Nema onih koji ga žbukom ožbukaše."},{"v":16,"t":"Nema izraelskih proroka koji Jeruzalemu proricahu i koji mu mir vidješe kad mira ne bijaše.' Tako govori Jahve Gospod.”"},{"v":17,"t":"“Sine čovječji, okreni lice protiv kćeri svojega naroda koje prorokuju po svojoj glavi! Prorokuj protiv njih:"},{"v":18,"t":"Ovako govori Jahve Gospod: 'Jao onima koje vezu poveze za svačije ruke i koje prave prijevjese za glave svake veličine da ulove duše! Mislite li uloviti sve duše mojega naroda a svoje duše sačuvati žive?"},{"v":19,"t":"Obeščašćujete me pred mojim narodom za šaku ječma, za zalogaj kruha, ubijajući duše koje ne bi trebale da umru, a spasavajući one koje ne bi trebale da žive; i obmanjujete tako narod moj koji rado sluša vaše laži.'"},{"v":20,"t":"Zato ovako govori Jahve Gospod: 'Evo me protiv vaših poveza kojima lovite duše kao ptice! Rastrgat ću sve to na vašim rukama i oslobodit ću duše koje time hvatate kao ptice!"},{"v":21,"t":"Poderat ću vaše prijevjese i oslobodit ću svoj narod da ne bude više plijen vaših ruku. I znat ćete da sam ja Jahve!"},{"v":22,"t":"Jer vi lažju ražalostiste srce pravednika, koje ja ražalostiti ne htjedoh, a okrijepiste ruke bezbožnika da se ne obrati od zla puta bezbožničkog pa da život spasi."},{"v":23,"t":"Zato nećete više vidjeti isprazno niti ćete laž proricati: ja ću osloboditi narod svoj iz vaših ruku. I znat ćete da sam ja Jahve!'”"}]},"14":{"hr":[{"v":1,"t":"Uto k meni dođoše neki od starješina Izraelovih i sjedoše preda me."},{"v":2,"t":"I dođe mi riječ Jahvina:"},{"v":3,"t":"“Sine čovječji! Ti ljudi nose kumire u srcu i upiru oči u ono što ih na grijeh potiče. Pa zar da trpim da u mene traže savjeta?"},{"v":4,"t":"Zato im reci: Ovako govori Jahve Gospod: 'Tko god iz doma Izraelova nosi u srcu kumire i upire oči u ono što ga na grijeh potiče, a dolazi k proroku, ja, Jahve, odgovorit ću mu prema mnoštvu njegovih kumira,"},{"v":5,"t":"da uhvatim za srce dom Izraelov koji se zbog idola svojih odmetnu od mene.'"},{"v":6,"t":"Zato reci domu Izraelovu: Ovako govori Jahve Gospod: 'Obratite se, odvratite se od kumira svojih! Odvratite lice od gnusoba svojih!"},{"v":7,"t":"Jer tko se god iz doma Izraelova i od došljaka koji se nastaniše u Izraelu odmetne od mene i u srcu nosi kumire i upire oči u ono što ga potiče na grijeh, pa unatoč tome dođe k proroku da preko njega u mene traži savjeta, njemu ću ja, Jahve, sam odgovoriti;"},{"v":8,"t":"okrenut ću se protiv njega i učinit ću od njega poslovičan primjer: iskorijenit ću ga iz svojega naroda! I znat ćete da sam ja Jahve."},{"v":9,"t":"Ako li se prorok dadne zavesti i progovori, bilo bi to kao da sam ja, Jahve, zaveo toga proroka: ruku ću podići na njega i iskorijenit ću ga iz svojega naroda izraelskoga."},{"v":10,"t":"Obojica će podjednako snositi grijeh svoj: grijeh prorokov jednak je grijehu onoga koji je u njega tražio savjeta."},{"v":11,"t":"I tako se dom Izraelov više neće odmetati od mene i neće se više kaljati svojim opačinama: on će biti narod moj, a ja ću biti njegov Bog' - riječ je Jahve Gospoda.”"},{"v":12,"t":"I dođe mi riječ Jahvina:"},{"v":13,"t":"“Sine čovječji, zgriješi li koja zemlja protiv mene nevjerom i ja podignem ruku na nju te joj uništim i posljednju pričuvu kruha i pustim na nju glad da zatrem u njoj sve ljude i stoku;"},{"v":14,"t":"preostanu li u njoj samo tri čovjeka - Noa, Daniel i Job - ti će se svojom pravednošću spasiti - riječ je Jahve Gospoda."},{"v":15,"t":"Također, ako na tu zemlju pustim divlje zvijeri da joj djecu unište a nju pretvore u pustinju, kojom se zbog zvijeri više nitko neće usuditi proći;"},{"v":16,"t":"preostanu li u njoj samo ta tri čovjeka, života mi moga - riječ je Jahve Gospoda - oni neće spasiti ni sinova ni kćeri nego samo sebe, a zemlja će njihova postati prava pustinja."},{"v":17,"t":"Ili, ako ja trgnem mač na tu zemlju govoreći: 'Maču, prođi ovom zemljom!' da istrijebim u njoj sve ljude i stoku,"},{"v":18,"t":"a u njoj se nađu samo ona tri čovjeka, života mi moga - riječ je Jahve Gospoda - oni neće spasiti ni sinova ni kćeri nego samo sebe."},{"v":19,"t":"Ili, ako ja pošaljem na tu zemlju kugu te izlijem na nju gnjev i pokolj da zatrem u njoj sve ljude i stoku,"},{"v":20,"t":"a u njoj preostanu samo ona tri čovjeka, Noa, Daniel i Job, života mi moga - riječ je Jahve Gospoda - oni neće spasiti ni sinova ni kćeri nego samo sebe svojom pravednošću.”"},{"v":21,"t":"Ovako govori Jahve Gospod: “Ipak, ako na Jeruzalem pustim sva svoja četiri ljuta biča - mač, glad, divlju zvjerad i kugu - da zatrem u njemu sve ljude i stoku,"},{"v":22,"t":"u njemu će ipak preživjeti Ostatak koji će spasiti sinove i kćeri. I evo, oni će doći k vama da vidite njihovo vladanje i njihova djela i da se utješite, jer ćete upoznati: što god poduzeh protiv Jeruzalema, ne učinih bez razloga."},{"v":23,"t":"Da, kad vidite njihovo vladanje i njihova djela, utješit ćete se, jer ćete upoznati da ne učinih bez razloga što god poduzeh protiv Jeruzalema - riječ je Jahve Gospoda.”"}]},"15":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji! U čemu je trs loze bolji od drugih šumskih drveta?"},{"v":3,"t":"Služi li da se od njega štogod načini? Djelja li se od njega klin da se o njega što objesi?"},{"v":4,"t":"Gle, baca se u oganj da izgori: kad mu oganj sažeže oba kraja i sredinu spali, može li još čemu poslužiti?"},{"v":5,"t":"Eto, ni onda kad bijaše čitav ništa se od njega ne mogaše načiniti. Pa kako će, dakle, čemu poslužiti kad ga plamen sažga?”"},{"v":6,"t":"Zato ovako govori Jahve Gospod: “Kao što sam trs loze, među drugim drvetima, bacio u oganj da izgori, tako ću postupati i s Jeruzalemcima!"},{"v":7,"t":"Upravit ću lice svoje na njih, i kada se iz jednog ognja izbave, drugi će ih proždrijeti. I spoznat ćete da sam ja Jahve kad lice svoje upravim na njih"},{"v":8,"t":"i svu im zemlju opustošim jer mi bijahu nevjerni! - riječ je Jahve Gospoda.”"}]},"16":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"Sine čovječji! Pokaži Jeruzalemu sve gadosti njegove!"},{"v":3,"t":"Reci: Ovako Jahve Gospod govori Jeruzalemu, nevjernici: 'Podrijetlom i rodom iz zemlje si kanaanske, otac ti Amorejac, mati Hetitkinja."},{"v":4,"t":"Kad si svijet ugledala, na dan rođenja tvojega pupka ti ne odrezaše niti te vodom opraše da te očiste; solju te ne osoliše niti te povojima poviše."},{"v":5,"t":"Nijedno se oko na te ne sažali niti se tko smilova da ti to učini, nego te na dan rođenja tvojega gadnu baciše napolje."},{"v":6,"t":"A ja prođoh kraj tebe i vidjeh gdje se koprcaš u krvi. I rekoh ti dok si još u krvi bila: 'Živi!' U krvi ti tvojoj rekoh: 'Živi!"},{"v":7,"t":"Razrasti se kao izdanak u polju!' I umnožih te, i ti se razraste i velika postade, i dođe vrijeme da sazreš. Dojke ti se raspupale, kosa ti narasla, ali si još gola i naga bila."},{"v":8,"t":"Prođoh kraj tebe i u te se zagledah: i gle, dob tvoja - dob je ljubavi! Raširih na te skute svoje i pokrih ti golotinju. Prisegoh ti i sklopih Savez s tobom - riječ je Jahve Gospoda - i ti moja postade."},{"v":9,"t":"Okupah te u vodi, krv saprah s tebe i uljem te pomazah."},{"v":10,"t":"Obukoh te u šarene haljine, na noge ti obuh sandale od fine kože; opasah te bezom i pokrih te prijevjesom svilenim."},{"v":11,"t":"Uresih te nakitima: na ruke ti stavih narukvice, oko vrata ogrlice;"},{"v":12,"t":"prstenom ti nos uresih, uši naušnicama, a glavu ti ovjenčah vijencem najljepšim."},{"v":13,"t":"I tako se sva u srebru i zlatu pojavi, u haljini od beza, svilom izvezenoj. Za hranu ti dadoh najfinije brašno, med i ulje. Bila si tako lijepa, prelijepa, za kraljicu podobna!"},{"v":14,"t":"Glas o ljepoti tvojoj puče među narodima, jer ti bijaše tako lijepa u nakitu mojem što ga djenuh na tebe - riječ je Jahve Gospoda."},{"v":15,"t":"Ali te ljepota tvoja zanijela, zbog glasa se svojega bludu podade: blud si svoj nudila obilno svakom prolazniku, njegova si bila."},{"v":16,"t":"Od haljina si svojih šarene uzvišice pravila i na njima se bludu odavala ..."},{"v":17,"t":"I nakite uze zlatne i srebrne, kojima te ja bijah uresio, i od njih načini sebi muške likove da s njima bludničiš."},{"v":18,"t":"Uze šarene, vezene haljine da njima odjeneš kumire svoje i njima si prinosila moje ulje i moj kad."},{"v":19,"t":"A hranu što ti je dadoh - najfinije brašno, med i ulje kojima te hranjah - pred njih si stavljala na ugodan miris. Da, tako to bijaše - riječ je Jahve Gospoda!"},{"v":20,"t":"Sinove si svoje i kćeri uzimala koje meni porodi i njima ih za hranu klala. Malo ti bijaše tvoga bludničenja,"},{"v":21,"t":"pa si čak i djecu moju davala da se njima na čast kroz oganj provedu!"},{"v":22,"t":"U svim tim gnusobama i bludu svojemu ne spomenu se dana mladosti svoje, kad si se gola i naga u krvi svojoj koprcala."},{"v":23,"t":"I povrh svega zla - Jao! Jao! riječ je Jahve Gospoda -"},{"v":24,"t":"sagradi sebi humke, posvud diže uzvišice."},{"v":25,"t":"Na svim raskršćima podiže uzvišice i na njima blatiš svoju ljepotu, nudiš se svakom prolazniku množeć' svoje bludničenje."},{"v":26,"t":"Bludu se podade sa sinovima Egipta, snažna tijela, bludničenje si množila da me razjariš."},{"v":27,"t":"Zato, evo, ruku digoh na te, smanjivši ti obrok hrane i predavši te bijesu tvojih mrziteljica, kćeri filistejskih, koje se stide sramotnoga tvojeg vladanja."},{"v":28,"t":"Tjerala si blud i sa sinovima Asira i nisi se zasitila; i s njima si blud tjerala, ali se nisi zasitila."},{"v":29,"t":"Umnožila si bludničenje svoje i sa zemljom kanaanskom, sa zemljom kaldejskom, ali se ni onda nisi zasitila."},{"v":30,"t":"O, kako li slabo bijaše tvoje srce - riječ je Jahve Gospoda - kad činjaše ono što rade bludnice najrazvratnije."},{"v":31,"t":"Na svim raskrsnicama humak sebi podiže, posvuda sagradi sebi uzvišice. Ali ne kao druge bludnice, jer si prezirala plaću bludničku,"},{"v":32,"t":"nego kao preljubnica: mjesto muža, strance si primala."},{"v":33,"t":"Svima se bludnicama plaća, a ti si sama ljubavnike svoje plaćala i još si ih u bludnosti svojoj darovima mamila da ti dođu odasvuda."},{"v":34,"t":"Ti bijaše bludnica kakvih nema: nitko za tobom nije trčao da s tobom blud provodi, nego si sama davala plaću bludničku, a nisu je tebi plaćali. Toliko si bila opaka!"},{"v":35,"t":"Stoga, razvratnice, čuj riječ Jahvinu:"},{"v":36,"t":"Ovako govori Jahve Gospod: Jer si svlačila svoju sramotu i u bludu golotinju otkrivala pred svima svojim ljubavnicima i gnusnim kumirima, i zbog krvi svojih sinova što si ih njima prinosila,"},{"v":37,"t":"evo, skupit ću sve tvoje ljubavnike s kojima si se naslađivala, sve koje si voljela i koje si mrzila, skupit ću ih odasvud protiv tebe i razotkriti im tvoju golotinju, neka vide sramotu tvoju."},{"v":38,"t":"Sudit ću ti kao što se sudi preljubnicama i krvnicama i predati te bijesu njihovu."},{"v":39,"t":"Predat ću te u ruke njihove da poruše tvoje humke, da razore uzvišice tvoje. I zderat će sa tebe haljine, oteti nakit i ostaviti te golu, sasvim nagu."},{"v":40,"t":"A zatim će na te dovesti svjetinu da te kamenuje i da te sasiječe mačevima."},{"v":41,"t":"Kuće će ti ognjem spaliti i naočigled svim ženama izvršiti pravdu nad tobom. Tako ću dokrajčiti tvoje bludničenje, nećeš više davati plaću bludničku."},{"v":42,"t":"Iskalit ću gnjev svoj nad tobom i povući ću svoju ljubomoru od tebe. Smirit ću se i neću se više gnjeviti."},{"v":43,"t":"I jer se ne spomenu svoje mladosti, već me svim tim izazivaše, oborit ću ti na glavu sve postupke tvoje - riječ je Jahve Gospoda: nećeš više dodavati bestidnosti na sve svoje gadosti!"},{"v":44,"t":"I sastavljač poslovica narugat će ti se poslovicom: 'Kakva mati, takva kći.'"},{"v":45,"t":"Prava si kći svoje matere, koja ostavi muža i djecu; sestra si sestara svojih, koje ostaviše muževe svoje i djecu: Hetitkinja vam mati bijaše, otac Amorejac:"},{"v":46,"t":"Samarija, sestra tvoja starija, sa svojim kćerima tebi slijeva stoji; Sodoma, tvoja mlađa sestra, sa kćerima svojim zdesna ti stoji."},{"v":47,"t":"A ti ne samo da si njihovim putem hodila i činila njihove gadosti - to bi tebi bilo premalo - već bijaše od njih pokvarenija na svojim putovima."},{"v":48,"t":"Života mi mojega - riječ je Jahve Gospoda - tvoja sestra Sodoma sa svojim kćerima ne učini što si ti počinila zajedno sa kćerima svojim."},{"v":49,"t":"Evo opačina sestre tvoje Sodome: gizdavo, u izobilju kruha i bezbrižno življaše ona i kćeri njezine, a sirotinju i bijednike ne pomagahu."},{"v":50,"t":"Uzoholiše se i gadosti pred očima mojim činjahu, i zato ih zatrijeh, kao što vidje!"},{"v":51,"t":"A sestra ti Samarija ne počini ni polovicu grijeha tvojih, i tako ti počini više gadosti nego one obje zajedno, opravdavši sestre svoje svojim gadostima."},{"v":52,"t":"Zato snosi sad sramotu grijeha kojima si sestre svoje opravdala; zbog grijeha kojima se više od njih nagrdi, one izađoše pravednije. Postidi se, dakle, i snosi sramotu svoju kojom sestre opravda."},{"v":53,"t":"A ja ću okrenuti udes njihov, udes Sodome i kćeri njenih, udes Samarije i kćeri njenih; i tvoj ću udes okrenuti među njima,"},{"v":54,"t":"da snosiš sramotu svoju i da se postidiš za sve što si počinila, njima na utjehu."},{"v":55,"t":"Sestra tvoja Sodoma i kćeri njene vratit će se u stanje prijašnje; sestra tvoja Samarija i kćeri njene vratit će se u stanje prijašnje; ali i ti i kćeri tvoje vratit ćete se u stanje prijašnje."},{"v":56,"t":"Zar se nije spominjala sestra tvoja Sodoma dok ti bijaše ponosita,"},{"v":57,"t":"prije negoli se golotinja tvoja otkrila? Budi sada za ruglo kćerima edomskim, susjedama njenim i kćerima filistejskim koje ti se sa svih strana rugaju."},{"v":58,"t":"Snosi, dakle, svoju sramotu i svoje gadosti - riječ je Jahve Gospoda!'"},{"v":59,"t":"Jer ovako govori Jahve Gospod: 'Postupit ću s tobom onako kako ti učini kad pogazi zakletvu i raskinu Savez."},{"v":60,"t":"Ali ću se ja ipak spomenuti svojega Saveza s tobom što ga sklopih u dane mladosti tvoje i uspostavit ću s tobom Savez vječan."},{"v":61,"t":"I ti ćeš se opomenuti svojih putova i postidjet ćeš se kad primiš svoje sestre, stariju i mlađu, koje ću ti dati za kćeri, ali ne snagom tvog Saveza."},{"v":62,"t":"Sklopit ću s tobom savez svoj i znat ćeš da sam ja Jahve,"},{"v":63,"t":"da se opomeneš i da se postidiš i da od sramote više ne otvoriš usta kad ti oprostim sve što učini! To je riječ Jahve Gospoda.'”"}]},"17":{"hr":[{"v":1,"t":"Dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, smisli zagonetku i iznesi prispodobu domu Izraelovu! Reci:"},{"v":3,"t":"'Ovako govori Jahve Gospod: Velik orao, velikih krila, duga perja, gusta, šarena paperja, doletje na Libanon i zgrabi cedrov vrh;"},{"v":4,"t":"odlomi mu najvišu grančicu, odnese je u zemlju trgovaca i spusti je u grad prodavača."},{"v":5,"t":"Onda uze izdanak iz zemlje, u plodnu ga njivu posadi, kraj obilnih voda stavi, kao vrbu usadi."},{"v":6,"t":"Izdanak proklija, bujan izbi čokot, onizak izraste, mladice mu k orlu segnuše, a pod njim mu žilje bješe; u bujan se razvi čokot, potjera izdanke, mladice razgrana."},{"v":7,"t":"Bijaše i drugi orao, velik i velikih krila, gusta perja. I gle, čokot k njemu žilje pruži, k njemu upravi grančice svoje da ga natapa bolje od tla u koje bi zasađen."},{"v":8,"t":"Na plodnoj njivi, kraj obilnih voda, bješe zasađen: mogao je tjerat' mladice, uroditi rodom, k'o veličanstveni trs izrasti.'"},{"v":9,"t":"Reci: 'Ovako govori Jahve Gospod: Hoće l' uspijevati? Neće l' mu orao sve žilje izguliti? Neće l' mu sve plodove potrgati? Neće l' mu sve mladice, čim izbiju, sasušiti? Da, i bez snažne mišice, i bez mnoštva naroda, iščupat će ga iz korijena!"},{"v":10,"t":"Gle, zasađen je! Hoće l' uspijevati? Čim ga takne istočnjak, neće l' sav usahnuti? Da, na lijehama iz kojih niče uvenut će.'”"},{"v":11,"t":"Dođe mi riječ Jahvina:"},{"v":12,"t":"“Reci domu odmetničkome: 'Zar ne znate što ovo znači?' Reci im: 'Eto, dođe kralj babilonski u Jeruzalem, zarobi mu kralja i sve knezove, odvede ih k sebi u Babilon."},{"v":13,"t":"Odvede i izdanak iz kraljevskoga koljena, sklopi s njima savez i zakletvom se obveza, pošto odvede sve mogućnike iz zemlje,"},{"v":14,"t":"da će kraljevstvo ostati neznatno i da se neće dizati, nego će čuvati i držati savez s njime."},{"v":15,"t":"Ali se on od njega odmetnu; poslanike uputi u Egipat, tražeći od njega konje i jaku vojsku. Hoće li uspjeti? Može li umaći onaj tko tako radi? Raskinu savez, pa da umakne?"},{"v":16,"t":"Života mi moga, riječ je Jahve Gospoda: jer prezre zakletvu kralja koji ga na prijestolje posadi i razvrže savez s njime, u njegovoj će zemlji umrijeti, usred Babilona!"},{"v":17,"t":"Svojom silnom vojskom i mnoštvom naroda faraon mu neće pomoći u boju kad onaj digne nasipe i sagradi kule opsadne da mu zatre mnogo ljudstvo."},{"v":18,"t":"Prezreo je zakletvu, razvrgao savez. Da, iako ruku bijaše dao, sve to učini! Ne, neće umaći!'"},{"v":19,"t":"Stoga ovako govori Jahve Gospod: 'Života mi moga, zakletvu što je prezre i savez što ga razvrže oborit ću na glavu njegovu!"},{"v":20,"t":"Mrežu ću nad njim razapeti i uhvatit će se u moju zamku, pa ću ga odvesti u Babilon i ondje mu suditi zbog nevjere kojom mi se iznevjeri."},{"v":21,"t":"Cvijet vojske njegove od mača će pasti, a ostatak se raspršiti u sve vjetrove. I spoznat ćete da ja, Jahve, tako rekoh.'"},{"v":22,"t":"Ovako govori Jahve Gospod: 'S vrha cedra velikoga, s vrška mladih grana njegovih, odlomit ću grančicu i posadit' je na gori visokoj, najvišoj."},{"v":23,"t":"Na najvišoj gori izraelskoj nju ću zasaditi: razgranat će se ona, plodom uroditi."},{"v":24,"t":"I sve će poljsko drveće znati da ja sam Jahve koji visoko drvo ponizujem, a nisko uzvisujem; zeleno drvo sušim, a drvu suhu dajem da rodi. Ja, Jahve, rekoh i učinit ću!'”"}]},"18":{"hr":[{"v":1,"t":"Dođe mi riječ Jahvina:"},{"v":2,"t":"“Što vam je te o Izraelu ponavljate poslovicu: 'Oci jedoše kiselo grožđe, sinovima trnu zubi!'"},{"v":3,"t":"Života mi moga, riječ je Jahve Gospoda: nitko od vas neće više u Izraelu ponavljati tu poslovicu;"},{"v":4,"t":"jer, svi su životi moji, kako život očev tako i život sinovlji. I evo, onaj koji zgriješi, taj će umrijeti."},{"v":5,"t":"Tko je pravedan i poštuje zakon i pravdu"},{"v":6,"t":"i ne blaguje po gorama i očiju ne podiže kumirima doma Izraelova, ne oskvrnjuje žene bližnjega svoga i ne prilazi ženi dok je nečista;"},{"v":7,"t":"nikomu ne nanosi nasilja, vraća što je u zalog primio i ništa ne otima; kruh svoj dijeli s gladnim, gologa odijeva,"},{"v":8,"t":"ne posuđuje uz dobit i ne uzima pridavka, ruku usteže od nedjela, po istini presuđuje,"},{"v":9,"t":"po mojim naredbama hodi i čuva moje zakone, postupajući po istini - taj je zaista pravedan i taj će živjeti, riječ je Jahve Gospoda."},{"v":10,"t":"Ali, porodi li on sina nasilnika, koji krv prolijeva ili bratu takvo što učini,"},{"v":11,"t":"a ne radi kao njegov roditelj, nego blaguje po gorama, oskvrnjuje ženu bližnjega;"},{"v":12,"t":"ubogu i bijednu nanosi nasilje, otima, ne vraća što je u zalog primio, oči podiže kumirima čineći gadosti;"},{"v":13,"t":"posuđuje uz dobit i uzima pridavak - ne, takav sin neće živjeti! Učinio je te gadosti i umrijet će, a krv će njegova na njega pasti."},{"v":14,"t":"A porodi li on sina koji uvidi sve grijehe što ih njegov otac počini, uvidi ih i tako više ne učini;"},{"v":15,"t":"ne blaguje po gorama, očiju ne podiže kumirima doma Izraelova, ne oskvrnjuje žene bližnjega;"},{"v":16,"t":"nikomu ne nanosi nasilja, ne prisvaja zaloga, ništa ne otima, kruh svoj dijeli s gladnim, gologa odijeva;"},{"v":17,"t":"ruku usteže od nedjela, ne uzima dobiti ni pridavka, vrši moje zakone i hodi po mojim naredbama - ne, taj neće umrijeti zbog grijeha očeva, on će živjeti."},{"v":18,"t":"A njegov otac, koji je nemilice tlačio i pljačkao bližnjega, čineći u narodu što ne valja, zbog svojega će grijeha umrijeti."},{"v":19,"t":"Ali vi kažete: 'Zašto da sin ne snosi očev grijeh?' Zato što sin vrši zakon i pravdu, čuva i vrši sve moje naredbe, živjet će."},{"v":20,"t":"Onaj koji zgriješi, taj će i umrijeti. Sin neće snositi grijeha očeva, ni otac grijeha sinovljega. Na pravedniku će biti pravda njegova, a na bezbožniku bezbožnost njegova."},{"v":21,"t":"Ako se bezbožnik odvrati od svih grijeha što ih počini, i bude čuvao sve moje naredbe i vršio zakon i pravdu, živjet će i neće umrijeti."},{"v":22,"t":"Sva njegova nedjela što ih počini bit će zaboravljena: zbog pravednosti što je čini, živjet će."},{"v":23,"t":"Jer, zar je meni do toga da umre bezbožnik - riječ je Jahve Gospoda - a ne da se odvrati od svojih zlih putova i da živi?"},{"v":24,"t":"Ako li se pravednik odvrati od svoje pravednosti i stane činiti nepravdu i sve gadosti koje radi bezbožnik - hoće li živjeti? Sva pravedna djela koja bijaše činio zaboravit će se, a zbog svoje nevjere kojom se iznevjerio i zbog grijeha što ih počini, umrijet će."},{"v":25,"t":"A vi velite: 'Put Jahvin nije pravedan!' Čuj, dome Izraelov: Moj put da nije pravedan? Nisu li vaši putovi nepravedni?"},{"v":26,"t":"Ako li se pravednik odvrati od svoje pravednosti i stane činiti nepravdu, pa zbog toga umre, umrijet će zbog nepravde što je počini."},{"v":27,"t":"A ako se bezbožnik odvrati od svoje bezbožnosti što je bijaše činio, pa stane vršiti moj zakon i pravdu, živjet će i neće umrijeti."},{"v":28,"t":"Jer je uvidio i odvratio se od svojih nedjela što ih bijaše počinio, živjet će i neće umrijeti."},{"v":29,"t":"Ali dom Izraelov kaže: 'Put Gospodnji nije pravedan!' Putovi moji da nisu pravedni, dome Izraelov? Nisu li vaši putovi nepravedni?"},{"v":30,"t":"Dome Izraelov, ja ću suditi svakome po njegovim putovima - riječ je Jahve Gospoda. Obratite se, dakle, i povratite od svih svojih nedjela, i grijeh vam vaš neće biti na propast!"},{"v":31,"t":"Odbacite od sebe sva nedjela koja ste činili i načinite sebi novo srce i nov duh! Zašto da umirete, dome Izraelov?"},{"v":32,"t":"Ja ne želim smrti nikoga koji umre - riječ je Jahve Gospoda. Obratite se, dakle, i živite!"}]},"19":{"hr":[{"v":1,"t":"A ti, sine čovječji, protuži tužaljkom za knezovima izraelskim."},{"v":2,"t":"Reci: Što bijaše tvoja mati? Lavica među lavovima, ležala je među lavićima, hraneći mladunčad svoju."},{"v":3,"t":"I othrani jedno mlado, koje lavom posta. Naučiv se plijen derati, stade ljude proždirati!"},{"v":4,"t":"Narodi se protiv njega udružiše, lav upade u jamu njihovu, na lancu ga odvedoše u zemlju egipatsku."},{"v":5,"t":"A kad mati vidje da uzalud čeka i da joj nada propade, uze drugo mlado i od njega lava učini."},{"v":6,"t":"Živeć' tako među lavovima, i on lavom posta. Naučiv se plijen derati, stade ljude proždirati,"},{"v":7,"t":"utvrde im rušiti, pustošiti gradove. Uzdrhta zemlja i sve na njoj od silne rike njegove."},{"v":8,"t":"Ali se ljudi iz okolnih mjesta protiv njega podigoše i zamke mu postaviše; i lav se uhvati u jamu njihovu."},{"v":9,"t":"Okovana u kavez ga zatvoriše, odvedoše kralju babilonskom, ondje ga u kulu zatočiše, da mu se više ne čuje rika po gorama izraelskim."},{"v":10,"t":"Mati tvoja bješe kao loza pokraj vode zasađena, rodna i granata od obilja vode!"},{"v":11,"t":"Imala je jaku granu za palicu vladalačku: uzdiže se nad krošnju, naočita visinom, mnoštvom grančica."},{"v":12,"t":"Al' u gnjevu bješe iščupana i na zemlju bačena. Istočnjak joj rod sasuši: polomi se i uvenu jaka grana njezina i vatra je svu proguta."},{"v":13,"t":"U pustinju bje presađena, u zemlju suhu, bezvodnu."},{"v":14,"t":"Al' liznu oganj iz pruta njezina i spali joj grane i plodove! I nema više na njoj grane jake za palicu vladalačku.” To je, evo tužaljka, i ostat će tužaljka."}]},"20":{"hr":[{"v":1,"t":"Godine sedme, petoga mjeseca, desetoga dana, dođoše k meni neke od starješina izraelskih da se s Jahvom svjetuju. Posjedaše preda me."},{"v":2,"t":"I dođe mi riječ Jahvina: “Sine čovječji! Govori starješinama Izraelovim!"},{"v":3,"t":"Reci im: Ovako govori Jahve Gospod: 'Došli ste me pitati za savjet? Života mi moga, nećete me pitati!' - riječ je Jahve Gospoda."},{"v":4,"t":"Hoćeš li im suditi, hoćeš li suditi, sine čovječji? Pokaži im gadosti otaca njihovih."},{"v":5,"t":"Reci im: Ovako govori Jahve Gospod: 'Onoga dana kad izabrah Izraela i ruku stavih na potomstvo doma Jakovljeva te im se objavih u zemlji egipatskoj, zakleh im se: Ja sam Jahve, Bog vaš!"},{"v":6,"t":"Toga im se dana rukom podignutom zakleh da ću ih izvesti iz zemlje egipatske u zemlju koju za njih izabrah, u zemlju kojom teče med i mlijeko, od svih zemalja najljepšu."},{"v":7,"t":"I rekoh im: Odbacite od sebe sve gadosti što vam oči privlače i ne kaljajte se kumirima egipatskim jer - ja sam Jahve, Bog vaš!'"},{"v":8,"t":"Ali se oni odvrgoše od mene i ne htjedoše me poslušati: nijedan ne odbaci gadosti koje mu oči zaniješe i ne okani se kumira egipatskih. Tad odlučih izliti gnjev svoj na njih i iskaliti srdžbu na njima u zemlji egipatskoj."},{"v":9,"t":"Ali radi imena svojega - da se ne kalja na oči naroda među kojima obitavahu i pred kojima im bijah objavio da ću ih izvesti -"},{"v":10,"t":"izvedoh ih iz zemlje egipatske i odvedoh ih u pustinju;"},{"v":11,"t":"i dadoh im svoje uredbe i objavih svoje zakone, koje svatko mora vršiti da bi živio;"},{"v":12,"t":"dadoh im i svoje subote, kao znak između sebe i njih, neka znaju da sam ja Jahve koji ih posvećujem."},{"v":13,"t":"Ali se i u pustinji dom Izraelov odmetnu od mene: nisu hodili po mojim uredbama; odbaciše moje zakone, koje svatko mora vršiti da bi živio; subote moje oskvrnjivahu. I zato odlučih u pustinji gnjev svoj na njih izliti da ih zatrem."},{"v":14,"t":"Ali ni toga ne učinih radi svojeg imena, da se ono ne kalja pred narodima kojima ih naočigled izvedoh."},{"v":15,"t":"Ali im se zakleh u pustinji da ih neću uvesti u zemlju koju sam im bio dao, u zemlju kojom teče med i mlijeko, od svih zemalja najljepšu,"},{"v":16,"t":"jer odbaciše moje zakone, i ne hodiše po mojim uredbama, i subote moje oskvrnjivahu, a srce im iđaše za njihovim kumirima."},{"v":17,"t":"Oči se moje ipak sažališe da ih ne zatrem. I tako ih u pustinji ne uništih,"},{"v":18,"t":"nego rekoh sinovima njihovim u pustinji: 'Ne hodite po uredbama svojih otaca, ne čuvajte zakona njihovih i ne kaljajte se kumirima njihovim!"},{"v":19,"t":"Ja sam Jahve, Bog vaš! Po uredbama mojim hodite, čuvajte i vršite moje zakone"},{"v":20,"t":"i svetkujte moje subote, neka one budu znak između mene i vas, kako bi se znalo da sam ja Jahve, Bog vaš!'"},{"v":21,"t":"Ali se i sinovi odmetnuše od mene: po mojim uredbama nisu hodili i nisu čuvali ni vršili mojih zakona, koje svatko mora vršiti da bi živio, a subote su moje oskvrnjivali. I zato odlučih gnjev svoj izliti i iskaliti srdžbu svoju na njima u pustinji."},{"v":22,"t":"Ali opet ruku svoju sustegoh radi svojeg imena, da se ono ne kalja pred narodima kojima ih naočigled izvedoh."},{"v":23,"t":"No zakleh se u pustinji da ću ih raspršiti među narode i rasijati po zemljama,"},{"v":24,"t":"jer nisu vršili mojih zakona i jer prezreše moje uredbe i jer subote moje oskvrnjivahu i oči upirahu u kumire svojih otaca."},{"v":25,"t":"I zato im dadoh uredbe koje ne bijahu dobre, zakone koji usmrćuju:"},{"v":26,"t":"da se oskvrnjuju svojim prinosima, provodeći kroz oganj svoju prvorođenčad. Htjedoh tako da ih zastrašim, neka znaju da sam ja Jahve."},{"v":27,"t":"Sine čovječji, reci domu Izraelovu: 'Ovako govori Jahve Gospod! I ovim me oci vaši još uvrijediše: nevjerom mi se iznevjeriše!"},{"v":28,"t":"Kad ih uvedoh u zemlju koju im se zakleh dati, gdje god bi ugledali povišen brežuljak ili stablo krošnjato, prinosili bi žrtve, donosili izazovne prinose, metali mirise ugodne, nalijevali ljevanice."},{"v":29,"t":"Upitah ih: što li znači ta uzvišica na koju se penjete?' I tako osta ime 'bama', uzvišica, do dana današnjega."},{"v":30,"t":"Zato reci domu Izraelovu: 'Ovako govori Jahve Gospod: Ne kaljate li se i vi kao oci vaši, ne provodite li i vi blud s gadostima njihovim?"},{"v":31,"t":"Kaljate se prinoseći im darove, provodeći kroz oganj svoje sinove u čast svim kumirima svojim sve do dana današnjega. I da me onda za savjet pitaš, dome Izraelov! Života mi moga - riječ je Jahve Gospoda - nećete me za savjet pitati!"},{"v":32,"t":"I neće se zbiti o čemu sanjate kad govorite: 'Bit ćemo kao drugi narodi, kao narodi ostalih zemalja što služe drveću i kamenju.'"},{"v":33,"t":"Života mi moga - riječ je Jahve Gospoda - vladat ću vama rukom krepkom i mišicom uzdignutom, u svoj žestini svoje jarosti."},{"v":34,"t":"Izvest ću vas iz naroda, skupiti vas iz svih zemalja u koje bijaste raspršeni rukom krepkom i mišicom uzdignutom, u svem plamu jarosti moje!"},{"v":35,"t":"Odvest ću vas u pustinju naroda i ondje vam licem u lice suditi!"},{"v":36,"t":"Kao što sudih ocima vašim u pustinji zemlje egipatske, i vama ću suditi - riječ je Jahve Gospoda!"},{"v":37,"t":"Provest ću vas ispod štapa svojega, podvrći vas brojenju:"},{"v":38,"t":"razlučit ću između vas sve koji se pobuniše i odvrgoše od mene: izvest ću ih iz zemlje u kojoj kao došljaci borave, ali - u zemlju Izraelovu nikad ući neće! I znat ćete da sam ja Jahve!'"},{"v":39,"t":"'A vi, dome Izraelov' - ovako govori Jahve Gospod - 'samo idite i dalje služite svaki svom kumiru! Jednom ćete, kunem vas se, poslušati i nećete više kaljati moje sveto ime svojim prinosima i kumirima:"},{"v":40,"t":"na Svetoj gori mojoj, na visokoj gori Izraelovoj - riječ je Jahve Gospoda - služit će mi sav dom Izraelov, u svojoj zemlji. Ondje će mi oni omiljeti i ondje ću iskati vaše podizanice i prinose vaših prvina sa svim svetinjama."},{"v":41,"t":"Omiljet ćete mi kao miris ugodan kad vas izvedem iz narodÄa i skupim iz zemalja u kojima bjeste rasijani. I na vama ću očitovati svetost svoju naočigled svih naroda."},{"v":42,"t":"Tada ćete znati da sam ja Jahve, kada vas dovedem u zemlju Izraelovu, u zemlju koju se zakleh dati očevima vašim."},{"v":43,"t":"Ondje ćete se spomenuti svih svojih putova i nedjela kojima se okaljaste: sami ćete sebi omrznuti zbog nedjela što ih počiniste."},{"v":44,"t":"I tada ćete spoznati da sam ja Jahve kad, radi imena svojega, ne postupim s vama po zloći vaših putova ni po vašim pokvarenim djelima, dome Izraelov! Tako govori Jahve Gospod!'”"}]},"21":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, okreni lice k jugu i prospi besjedu prema jugu te prorokuj protiv šume u kraju negepskom."},{"v":3,"t":"Reci šumi negepskoj: 'Poslušaj riječ Jahvinu! Ovako govori Jahve Gospod: Evo, zapalit ću usred tebe oganj i on će proždrijeti u tebi svako drvo, zeleno i suho! Razgorjeli se oganj neće utrnuti dok sve ne izgori od sjevera do juga."},{"v":4,"t":"I svi će vidjeti da sam ja, Jahve, zapalio taj oganj i neće se ugasiti.'”"},{"v":5,"t":"Rekoh na to: “Jao, Jahve Gospode, tÓa oni će za mene reći: 'Evo opet pričalice s pričama!'”"},{"v":6,"t":"I dođe mi riječ Jahvina:"},{"v":7,"t":"“Sine čovječji, okreni lice prema Jeruzalemu i prospi besjedu protiv njegova Svetišta i prorokuj protiv zemlje Izraelove."},{"v":8,"t":"Reci zemlji Izraelovoj: 'Ovako govori Jahve Gospod: Evo me na te! Trgnut ću mač iz korica, istrijebit ću iz tebe sve - i pravedna i bezbožna!"},{"v":9,"t":"Da iz tebe istrijebim pravedna i bezbožna, trgnut ću evo mač iz korica na svako tijelo, od sjevera do juga."},{"v":10,"t":"I svako će tijelo spoznati da sam ja, Jahve, isukao mač svoj iz korica i da ga više neću u njih vratiti!"},{"v":11,"t":"A ti, sine čovječji, kukaj kao da su ti sva rebra polomljena, kukaj gorko, njima na oči!"},{"v":12,"t":"Ako li te zapitaju: 'Što toliko kukaš?' reci im: 'Zbog vijesti koja stiže, od koje će sva srca zamrijeti i sve ruke klonuti, svaki duh biti utučen i svako koljeno klecati. Evo, dolazi, već je tu!' Tako govori Jahve Gospod.”"},{"v":13,"t":"I dođe mi riječ Jahvina:"},{"v":14,"t":"“Sine čovječji, prorokuj! Ovako govori Jahve Gospod. Reci: 'Mač! Mač! Naoštren i osvjetlan!"},{"v":15,"t":"Za klanje naoštren, osvjetlan da sijeva."},{"v":16,"t":"Osvjetlan da ga ruka prihvati, mač naoštren, osvjetlan da se stavi u ruke ubojici."},{"v":17,"t":"A ti, sine čovječji, plači, nariči! Jer, evo, mač je već na narod moj isukan, mač na izraelske knezove: svi su oni s mojim narodom maču izručeni! Udri se stoga u slabine!'"},{"v":18,"t":"Dođe kušnja, i odbačenoga žezla više biti neće - riječ je Jahve Gospoda."},{"v":19,"t":"A ti, sine čovječji, prorokuj i rukama plješći. Neka se udvostruči, neka se utrostruči taj mač pokolja, mač pokolja golema što ih odasvud okružuje."},{"v":20,"t":"Da zadršću srca, da bude žrtava nebrojenih, na svaka sam vrata postavio mač, pripravljen da k'o munja sijeva, za pokolje naoštren."},{"v":21,"t":"Natrag! Desno! Naprijed! Lijevo!"},{"v":22,"t":"I ja ću pljeskati rukama, iskaliti gnjev svoj na njima! Ja, Jahve, rekoh!”"},{"v":23,"t":"I dođe mi riječ Jahvina:"},{"v":24,"t":"“Sine čovječji, zacrtaj dva puta kuda da pođe mač kralja babilonskoga. Neka oba puta izlaze iz iste zemlje! Na raskršću puta ka gradu stavi putokaz."},{"v":25,"t":"Zacrtaj maču put da dođe u Rabat Bene Amon i u Judeju, u utvrđeni Jeruzalem."},{"v":26,"t":"Jer kralj babilonski stoji na početku puta, na raspuću dvaju putova, i pita znamenja - miješa strijele, ispituje terafime i motri jetru."},{"v":27,"t":"Znamenja mu u desnici kažu: na Jeruzalem; da ondje namjesti zidodere, da naredi pokolj, da podigne zidodere protiv vrata, da naspe nasip i sagradi opsadne kule."},{"v":28,"t":"Ali će se njima učiniti da je znamenje lažno, jer mu se zakleše na vjernost. Ali će ih on tada podsjetiti na njihovo vjerolomstvo u koje se uloviše."},{"v":29,"t":"Zato, ovako govori Jahve Gospod: 'Jer bez prestanka podsjećate na svoja bezakonja otkrivajući opačine i pokazujući grijehe u svim svojim djelima - da, jer bez prestanka na njih podsjećate, u njih ćete se uloviti."},{"v":30,"t":"A tebi, nečasni i bezbožnički kneže izraelski, tebi dođe dan i čas posljednjega zločina.'"},{"v":31,"t":"Ovako govori Jahve Gospod: 'Skini mitru s glave i odloži kraljevski vijenac! Jer sve se mijenja: tko bi dolje, bit će uzvišen, a tko bi gore, bit će ponižen."},{"v":32,"t":"Ruševine, ruševine, ruševine ću postaviti kakvih nije bilo, dok ne dođe onaj koji ima suditi, jer ja ću mu predati sud.'"},{"v":33,"t":"Sine čovječji, prorokuj: Ovako govori Jahve Gospod sinovima Amonovim o njihovoj sramoti. Reci: 'Mač! Mač za pokolj isukan i naoštren da siječe, da kao munja sijeva,"},{"v":34,"t":"a tebi dotle isprazno viđaju, laž proriču - da se stavi pod vrat zlikovcima zloglasnim, kojima, eto, dođe dan i čas posljednjega zločina!"},{"v":35,"t":"Ali vrati mač u korice! U mjestu gdje si nastao i u zemlji gdje si se rodio ja ću ti suditi."},{"v":36,"t":"Ondje ću na te gnjev svoj izliti i raspiriti protiv tebe plamen srdžbe svoje i predati te u ruke okrutnim ljudima, vještim zatornicima."},{"v":37,"t":"I bit ćeš hrana ognju, a krv će tvoja zemljom protjecati. I nitko te živ više neće spominjati! Jer ja, Jahve, tako rekoh.'”"}]},"22":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, hoćeš li suditi, hoćeš li suditi gradu krvničkom? Pokaži mu sve gnusobe njegove!"},{"v":3,"t":"Reci: 'Ovako govori Jahve Gospod: Grade što u sebi krv toliku prolijevaš i što svuda sebi kumire praviš da se okaljaš, kucnu čas tvoj:"},{"v":4,"t":"krvlju što je proli ti sagriješi i kumirima koje napravi ti se okalja, skrativši tako dane svoje i ubrzavši svoje godine. I zato ću te sada učiniti sramotom među narodima, ruglom po svim zemljama."},{"v":5,"t":"I koji su ti blizu i koji su ti daleko, podrugivat će se tebi: 'O sramotno ime, grade pokvareni!'"},{"v":6,"t":"Eto, knezovi izraelski - svaki na svoju ruku - u tebi krv prolijevaju."},{"v":7,"t":"I u tebi se više ne poštuje ni otac ni majka, došljake tlače, siročad i udovice u tebi zlostavljaju!"},{"v":8,"t":"Svetinje moje prezireš, subote oskvrnjuješ."},{"v":9,"t":"U tebi su klevetnici zbog kojih se krv prolijeva; u tebi se po gorama blaguje, posred tebe čine sramote."},{"v":10,"t":"U tebi se raskriva sramota očeva, u tebi siluju žene dok su nečiste."},{"v":11,"t":"Jedan čini gadost sa ženom susjeda svoga, drugi djelom sramotnim oskvrnjuje snahu svoju, a treći u tebi siluje sestru, kćerku oca svoga."},{"v":12,"t":"Ima ih koji i mito primaju da krv proliju. Uzimaš ujam i pridatak, od bližnjega silom otimaš, a mene zaboravljaš - riječ je Jahve Gospoda."},{"v":13,"t":"Zato, evo, ja rukama plješćem nad plijenom što ga ti napljačka i nad krvlju što se lije u tebi."},{"v":14,"t":"Jer, hoće li srce tvoje izdržati i hoće li ruke tvoje odoljeti u dane kad ja na te ustanem? Ja, Jahve, rekoh i učinit ću!"},{"v":15,"t":"Zato ću te raspršiti među narode, rasijat' te po zemljama, da uklonim iz tebe svu nečistoću!"},{"v":16,"t":"I bit ćeš opet moja baština naočigled naroda. I znat ćeš da sam ja Jahve!'”"},{"v":17,"t":"Dođe mi riječ Jahvina:"},{"v":18,"t":"“Sine čovječji, dom Izraelov troska mi postade: bakar, srebro, kositar, željezo i olovo u peći - svi su oni troska!"},{"v":19,"t":"Stoga ovako govori Jahve Gospod: 'Jer mi troska postadoste, skupit ću vas, evo, u Jeruzalemu."},{"v":20,"t":"Kao što se skuplja srebro, bakar, željezo, olovo i kositar u peći te se okolo oganj potpiri da se sve rastali, tako ću i ja vas skupiti u svojem gnjevu i u svojoj jarosti, složiti vas i rastaliti."},{"v":21,"t":"Jest, skupit ću vas i potpiriti oko vas oganj svoje jarosti da se usred grada rastalite."},{"v":22,"t":"Kao što se srebro u peći topi, tako ćete se i vi u njemu rastopiti. I znat ćete da ja, Jahve, gnjev svoj na vas izlijevam!'”"},{"v":23,"t":"Dođe mi riječ Jahvina:"},{"v":24,"t":"“Sine čovječji, reci još: 'Ti si zemlja još neočišćena, koju još ne opra kiša dana jarosnoga!"},{"v":25,"t":"Knezovi njezini, poput lavova što riču i plijen razdiru, ljude proždiru, otimlju im blago i dragocjenosti, množeći udovice usred nje."},{"v":26,"t":"Svećenici njezini ne poštuju mog Zakona i oskvrnjuju moje svetinje, ne razlikujući sveto od nesvetoga, ne učeći se lučiti nečisto od čistoga. Zanemarili su subote moje, bez časti sam u njihovoj sredini."},{"v":27,"t":"Starješine njezine, poput vukova što plijen razdiru i krv prolijevaju, upropašćuju ljude, lakomi na dobitak."},{"v":28,"t":"A proroci njezini sve to premazuju bjelilom i prekrivaju ispraznim viđenjima i lažnim proricanjima zboreći: 'Ovako govori Jahve Gospod!' - a Jahve to ne reče."},{"v":29,"t":"Imućnici pak čine svakojaka nasilja i otimačine, siromaha i bijednika ugnjetavaju, a došljaka bespravno tlače."},{"v":30,"t":"Tražio sam među njima nekoga da podigne zidine i stane na proboje preda me u obranu zemlje, da je ne zatrem, i ne nađoh nikoga."},{"v":31,"t":"I zato izlih na njih gnjev svoj pa ih zatrijeh ognjem svoje jarosti; putove im njihove na glavu oborih' - riječ je Jahve Gospoda.”"}]},"23":{"hr":[{"v":1,"t":"Dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, bile dvije žene, kćeri jedne matere."},{"v":3,"t":"I odaše se bludu u Egiptu, blud činiše u mladosti: ondje su im grudi stiskali, djevojačke dojke gnječili."},{"v":4,"t":"Starijoj bijaše ime Ohola, a sestri joj Oholiba. Obje moje postadoše i rodiše mi sinove i kćeri. Evo im imenÄa: Samarija je Ohola, Jeruzalem Oholiba."},{"v":5,"t":"Ohola, iako meni pripadaše, bludu se odala; uspalila se za ljubavnicima, za Asircima, susjedima svojim,"},{"v":6,"t":"u modri baršun odjevenima, sve samim vojvodama i namjesnicima, pristalim momcima, vještim konjanicima."},{"v":7,"t":"I oda se bludu s njima, sve poizbor sinovima asirskim; i usplamtjev za njima, okalja se svim njihovim kumirima."},{"v":8,"t":"A ne okani se ni bluda s Egipćanima, koji s njome ležahu od njezine mladosti, koji su joj djevojačke dojke gnječili i na nju blud svoj izlijevali."},{"v":9,"t":"I zato je predah u ruke njenim ljubavnicima, u ruke Asircima za kojima se uspalila."},{"v":10,"t":"I oni je razgoliše, zarobiše joj sinove i kćeri, a nju samu mačem pogubiše. I postade tako primjer svim ženama kako na njoj bi sud izvršen."},{"v":11,"t":"Vidje to sestra joj Oholiba, ali se još gore uspali i gori blud činjaše."},{"v":12,"t":"Za sinovima se asirskim uspaljivala, sve samim vojvodama i namjesnicima, svojim susjedima, raskošno odjevenim, vještim konjanicima, poizbor momcima."},{"v":13,"t":"I vidjeh kako se okaljala: obje su istim putem pošle."},{"v":14,"t":"Ali se ova još gore bludu odala: kad bi ugledala muškarca na zidu naslikana, likove Kaldejaca crvenilom nacrtane,"},{"v":15,"t":"bedara pasom opasanih, sa spuštenim povezima na glavama - sve junake, prave Babilonce, rodom iz zemlje kaldejske -"},{"v":16,"t":"tek što bi ugledala priliku njihovu, sva bi se za njima uspalila te im slala poslanike u zemlju kaldejsku."},{"v":17,"t":"Sinovi babilonski k njoj bi dohrlili na ljubavnu postelju da je bludom kaljaju. A kad bi se s njima okaljala, zgadili bi joj se."},{"v":18,"t":"Ali se razglasilo njezino bludništvo, otkrila se njena golotinja, i duša se moja od nje odvratila, kao što se bješe odvratila od sestre njene."},{"v":19,"t":"Jer ona se još gorem bludu predala, opominjući se dana svoje mladosti kad se u Egiptu bludu odavala,"},{"v":20,"t":"uspaljujući se za razvratnicima kojima muška snaga bijaše kao u magaraca, a izljev kao u pastuha."},{"v":21,"t":"Tako se opet vrati sramoti svoje mladosti, kad su joj u Egiptu grudi pritiskivali, djevičanske dojke gnječili."},{"v":22,"t":"Zato, Oholibo, ovako govori Jahve Gospod: 'Gle, dignut ću na te tvoje ljubavnike, koji ti se duši ogadiše, i dovest ću ih odasvud na tebe:"},{"v":23,"t":"Babilonce, sve Kaldejce, Pekođane, Šoance i Koance, a s njima sve sinove asirske - sve poizbor momke, vojvode i namjesnike, na glasu junake, vješte konjanike."},{"v":24,"t":"I doći će na te sa sjevera sila bojnih kola i točkova s mnoštvom naroda i svrstat' se odasvud protiv tebe sa štitovima, štitićima i oklopima. Njima ću te na sud predati, i svojim će ti sudom suditi."},{"v":25,"t":"Oborit ću na te svu svoju ljubomoru, neka s tobom jarosno postupe: nos i uši neka ti odsijeku, a ostatak tvoj da od mača padne; sinove i kćeri da ti odvedu, a ostatak tvoj da oganj proguta."},{"v":26,"t":"I zderat će s tebe tvoje haljine i oteti sve tvoje nakite."},{"v":27,"t":"Tako ću okončati svu tvoju sramotu i bludničenje, sve tamo od Egipta: nećeš više k njima oči dizati i nećeš se više spominjati Egipta!'"},{"v":28,"t":"Jer, ovako govori Jahve Gospod: 'Evo me! Predat ću te u ruke onima koji ti omrznuše, koji ti se duši ogadiše."},{"v":29,"t":"Neka iskale na tebi svoju mržnju, neka ti svu muku preotmu, a tebe nek' ostave golu i nagu! Neka se obnaži sva golotinja tvoje bludnosti i besramnosti, tvojeg bludničenja."},{"v":30,"t":"Sve će te to stići zbog tvojeg bludničenja s narodima i jer si se okaljala njihovim kumirima."},{"v":31,"t":"Putem si sestre svoje hodila: dat ću ti u ruku čašu njezinu:"},{"v":32,"t":"Ovako govori Jahve Gospod: Čašu sestre svoje ispit ćeš, čašu široku, duboku, i bit ćeš na podsmijeh i ruglo - mnogo u nju stane! -"},{"v":33,"t":"napunit ćeš se pijanstva i žalosti! Čaša je to pustošenja, užasa - čaša sestre tvoje Samarije."},{"v":34,"t":"Pit ćeš je, do dna iskapiti, zatim u komade razbiti, grudi svoje izraniti. Jer, ja tako rekoh' - riječ je Jahve Gospoda!"},{"v":35,"t":"Stoga ovako govori Jahve Gospod: 'Jer ti mene zaboravi i leđa mi okrenu, snosi sada svu svoju sramotu i bestidnost!'”"},{"v":36,"t":"I još mi reče Jahve: “Sine čovječji, hoćeš li suditi Oholi i Oholibi, pokazati im njihove gadosti?"},{"v":37,"t":"Preljub počiniše, ruke su im okrvavljene, s kumirima svojim preljub učiniše, djecu koju mi porodiše provedoše kroz oganj da ih proguta."},{"v":38,"t":"Još mi i ovo učiniše: onoga dana obeščastiše moje Svetište i subote moje oskvrnuše."},{"v":39,"t":"Jer istoga dana kad djecu svoju kumirima klaše, u Svetište moje dođoše da ga obeščaste. Eto, tako uradiše usred Doma mojega."},{"v":40,"t":"Slale su čak po muškarce izdaleka, i oni bi im pohrlili čim bi glasnici k njima stigli. A ti se za njih kupala, oči svoje mazala i nakitom se kitila."},{"v":41,"t":"A potom bi sjedala na raskošnu postelju pred kojom stol prostrt bijaše na koji si stavljala moj tamjan i moje ulje."},{"v":42,"t":"Tu se čulo pocikivanje bezbrižnog društva zbog velikog mnoštva dovedena sa svih strana pustinje; stavljali su ženama na ruke narukvice i na glavu vijence prekrasne."},{"v":43,"t":"I rekoh: 'Sa ženom ogrezlom u preljubu još blud tjeraju, i sama se ona još bludu odaje!'"},{"v":44,"t":"Prilaze joj kao kakvoj bludnici! Da, prilazili su k Oholi i Oholibi, pokvarenicama."},{"v":45,"t":"Zato će im pravednici suditi kao što se sudi preljubnicama i onima koji krv prolijevaju, jer - one su preljubnice, ruke su im okrvavljene."},{"v":46,"t":"Jer ovako govori Jahve Gospod: 'Neka se protiv njih zbor sazove da ih izvrgnem zlostavljanju i pljački."},{"v":47,"t":"Zbor neka ih kamenuje i mačevima raskomada; sinove i kćeri neka im pokolje, a domove ognjem spali."},{"v":48,"t":"Tako ću iz zemlje istrijebiti sramotu, da se druge žene opomenu i ne čine djela vaših sramotnih."},{"v":49,"t":"A na vas ću oboriti svu vašu bestidnost, ispaštat ćete grijehe idolopoklonstva. I znat ćete da sam ja Jahve Gospod.'”"}]},"24":{"hr":[{"v":1,"t":"Godine devete, devetoga mjeseca, desetoga dana, dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, zapiši ovaj dan: upravo danas kralj babilonski zaposjede Jeruzalem."},{"v":3,"t":"Pripovijedaj domu odmetničkom prispodobu. Reci im: Ovako govori Jahve Gospod: 'Pristavi lonac, pristavi i nalij vode u nj!"},{"v":4,"t":"Baci u nj komade, sve najbolje komade mesa, but i pleće! Napuni ga ponajboljim kostima!"},{"v":5,"t":"Uzmi najbolje od stada. Pod loncem vatru naloži. Neka dobro uzavri, neka se u njemu skuhaju i kosti.'"},{"v":6,"t":"Jer ovako govori Jahve Gospod: 'Jao gradu krvničkom, zahrđalu loncu s kojega se hrđa ne skida! A zatim komad po komad iz njega izvadi, ali za nj ne bacaj kÓockÄe!"},{"v":7,"t":"Jer krv je njegova u njemu - na golu je kamenu ostavi, po zemlji je ne razlij gdje bi je prašina mogla prekriti!"},{"v":8,"t":"Da se gnjev moj raspali, da mu odmazdim, ostavih krv njegovu na kamenu golom, da se ne pokrije.'"},{"v":9,"t":"Stoga ovako govori Jahve Gospod: 'Jao gradu krvničkome, jer ću veliku lomaču naložiti!"},{"v":10,"t":"Skupi drva, vatru potpali, skuhaj meso, primiješaj začina, nek' izgore i kosti!"},{"v":11,"t":"A zatim ga prazna na žeravicu pristavi da mjed mu se usija i nečistoća njegova sva se rastopi, da se uništi hrđa na njemu!"},{"v":12,"t":"Grdne li muke! Ali se velika hrđa ne dade s njega skinuti: i vatri odolje."},{"v":13,"t":"Sramotan je grijeh tvoj: htjedoh te očistiti, ali se ti ne htjede od grijeha očistiti; i zbog toga se više nećeš očistiti dok nad tobom ne iskalim gnjev svoj!"},{"v":14,"t":"Ja, Jahve, rekoh! I riječ ću ispuniti; neću popustiti: I neću se smilovati niti ću se pokajati! Sudit ću te po putovima tvojim i po djelima tvojim! - riječ je Jahve Gospoda.”"},{"v":15,"t":"I dođe mi riječ Jahvina:"},{"v":16,"t":"“Sine čovječji, evo, nenadanom smrću oduzet ću ti radost očinju! Ne tuguj, ne plači i ne roni suza!"},{"v":17,"t":"Jecaj tiho, ali ne žali kao što se za mrtvima žali! I povij oko glave povez, a na noge obuj sandale. Ne prekrivaj brade i ne jedi žalobničke pogače.”"},{"v":18,"t":"Ujutro tako prorokovah narodu, a uveče mi žena umrije te sutradan uradih kao što mi bijaše zapovjeđeno."},{"v":19,"t":"Narod me na to zapita: “Nećeš li nam reći što znači za nas to što ti radiš?”"},{"v":20,"t":"Ja im odgovorih: “Dođe mi riječ Jahvina:"},{"v":21,"t":"“Reci domu Izraelovu: Ovako govori Jahve Gospod: Evo, oskvrnut ću svoje Svetište, vaš ponos snažni, radost vam očinju i čežnju duše vaše! I sinovi i kćeri koje ostaviste, od mača će pasti!"},{"v":22,"t":"Tada ćete uraditi kao što i ja uradih: nećete prekrivati brade i nećete jesti žalobničke pogače!"},{"v":23,"t":"Povit ćete povez oko glave i obuti na noge sandale! I nećete više tugovati ni plakati, nego ćete čiljeti zbog svojih nedjela i jecati jedan za drugim!"},{"v":24,"t":"A Ezekiel će vam biti primjer: učinit ćete sve što je i on činio. Kad se to zbude, spoznat ćete da sam ja Jahve!'"},{"v":25,"t":"A ti, sine čovječji, doista u dan kad im oduzmem snagu, dičnu radost njihovu, radost im očinju, slast duše njihove, sinove i kćeri njihove -"},{"v":26,"t":"u taj će dan k tebi stići bjegunac da ti to dojavi!"},{"v":27,"t":"U taj će se dan tvoja usta otvoriti, i ti ćeš tom bjeguncu progovoriti; nećeš više biti nijem. I tako ćeš im biti znak. I oni će spoznati da sam ja Jahve!”"}]},"25":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, okreni lice k sinovima Amonovim te prorokuj protiv njih!"},{"v":3,"t":"Reci sinovima Amonovim: 'Poslušajte riječ Jahve Gospoda! Ovako govori Jahve Gospod: Zato što vi klicaste 'ha, ha!' nad mojim Svetištem kad ono bijaše oskvrnuto, i nad zemljom Izraelovom kad ona bijaše opustošena, i nad domom Judinim kad odlažaše u izgnanstvo,"},{"v":4,"t":"predat ću vas, evo, u posjed sinovima Istoka da usred vas razapnu svoje šatore, udare svoja prebivališta. Oni neka jedu tvoje plodove i piju mlijeko tvoje!"},{"v":5,"t":"Od Rabe ću pašnjake za deve načiniti, a u zemlji Amonovih sinova torove ću za ovce podići. I znat ćete da sam ja Jahve!'"},{"v":6,"t":"Jer ovako govori Jahve Gospod: 'Zato što si pljeskao rukama i udarao nogama i svom se dušom radovao nad zemljom Izraelovom,"},{"v":7,"t":"ja ću, evo, ruku na te podići i kao plijen te predati narodima! Istrijebit ću te iz narodÄa, iskorijeniti iz zemalja! Zatrijet ću te! I znat ćeš da sam ja Jahve!"},{"v":8,"t":"Ovako govori Jahve Gospod: 'Zato što Moab i Seir govorahu: 'Gle, dom je Judin poput svih naroda',"},{"v":9,"t":"otkrit ću, evo, obronke moapske, da s kraja na kraj ostane bez gradova što bijahu ukras zemlje: Bet Haješimot, Baal Meon i Kirjatajim."},{"v":10,"t":"Dat ću ih u posjed sinovima Istoka, neprijateljima Amonaca, da se sinovi Amonovi među narodima više ne spominju!"},{"v":11,"t":"Tako ću izvršiti sud nad Moabom. I znat će da sam ja Jahve!'"},{"v":12,"t":"Ovako govori Jahve Gospod: 'Zato što se Edom osveti domu Judinu i tom se osvetom teško ogriješi,"},{"v":13,"t":"ovako govori Jahve Gospod: Podići ću ruku na Edom, istrijebit ću iz njega ljude i životinje! Pretvorit ću ga u pustinju: od Temana do Dedana svi će od mača izginuti."},{"v":14,"t":"Tako ću se osvetiti Edomu rukom svojega naroda izraelskog. Oni će postupiti s Edomom prema mojem gnjevu i mojoj srdžbi. I spoznat će moju osvetu!' - riječ je Jahve Gospoda."},{"v":15,"t":"Ovako govori Jahve Gospod: 'Zato što Filistejci izvršiše odmazdu, krvavo se osvećujući s mržnjom u srcu, razarajući sve zbog svojeg neprijateljstva,"},{"v":16,"t":"ovako govori Jahve Gospod: Evo, podižem ruku na Filistejce, istrijebit ću Kerećane, uništit ću sve što preostane na morskoj obali!"},{"v":17,"t":"Tako ću im se strašno osvetiti kaznama jarosnim. I kad im se osvetim, znat će da sam ja Jahve.'”"}]},"26":{"hr":[{"v":1,"t":"Godine jedanaeste, prvoga dana u mjesecu, dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, jer Tir nad Jeruzalemom klicaše: 'Ha, ha! Razbiše se ta vrata narÄodÄa, i k meni se okrenuše; obogatit ću se: on je opustošen' -"},{"v":3,"t":"stoga ovako govori Jahve Gospod: 'Evo me protiv tebe, Tire, dići ću na te silne narode, kao što more valove diže!"},{"v":4,"t":"Porušit će zidine tirske i razoriti sve kule njegove. A ja ću mu i prašinu pomesti, načinit' od njega pećinu golu!"},{"v":5,"t":"Bit će sušilište mreža. Jer ja rekoh! - riječ je Jahve Gospoda. I narodima plijen će postati."},{"v":6,"t":"A sve kćeri njegove od mača će pasti u polju! Znat će da sam ja Jahve!'"},{"v":7,"t":"Jer ovako govori Jahve Gospod: 'Gle, dovest ću na Tir sa sjevera Nabukodonozora, kralja babilonskoga, kralja nad kraljevima, s konjima i bojnim kolima, s konjanicima, četama i mnoštvom naroda!"},{"v":8,"t":"Kćeri će tvoje u polju mačem posjeći! Protiv tebe dići će kule opsadne, nasuti protiv tebe nasipe i podić' protiv tebe štitove."},{"v":9,"t":"Na zidove će tvoje upraviti zidodere i tvoje će kule kukama oborit'!"},{"v":10,"t":"Od nebrojenih konja njegovih svega će te prašina prekriti, a od štropota konjanika i točkova i bojnih kola njihovih zadrhtat će zidine tvoje, kad bude prolazio kroz vrata tvoja, k'o što se prolazi kroz grad osvojen."},{"v":11,"t":"Kopitima svojih konja zgazit će ti sve ulice; narod tvoj mačem će pobiti i srušiti stupovlje tvoje."},{"v":12,"t":"Poplijenit će bogatstvo tvoje, tvoje će razgrabiti blago! Razorit će tvoje zidine i kuće tvoje divne srušiti! Kamenje, drvo, prašinu tvoju u more će pobacati!"},{"v":13,"t":"A ja ću prekinuti jeku tvojih pjesama, i zvuk se tvojih harfa više neće čuti!"},{"v":14,"t":"Pretvorit ću te u pećinu golu, postat ćeš sušilište mrežÄa. Više se nikad nećeš podići, jer ja, Jahve, rekoh!' - to riječ je Jahve Gospoda.”"},{"v":15,"t":"Ovako Jahve Gospod govori Tiru: “A neće li od trijeska pada tvojega i jecanja tvojih ranjenika, kad nastane u tebi pokolj nemili, zadrhtati svi otoci?"},{"v":16,"t":"I neće li tada svi morski knezovi sići s prijestolja svojih, odbaciti svoje plašteve, i skinuti vezene haljine, u strah se zaodjeti, na zemlju posjedati, dršćući bez prestanka, užasnuti tvojim udesom?"},{"v":17,"t":"A zatim će nad tobom zakukati i reći ti: 'Kamo li propade? Kamo li s mora nestade, grade proslavljeni, što bijaše tako moćan na moru, ti i žitelji tvoji, koji strah zadavahu zemlji svoj?"},{"v":18,"t":"Sada na dan pada tvojega otoci će zadrhtati, otoci u moru prestravit će se zbog propasti tvoje!'"},{"v":19,"t":"Jer ovako govori Jahve Gospod: 'Kad te pretvorim u pusti grad, kakvi su gradovi u kojima više nitko ne boravi, i kada na tebe dovedem bezdane da te velike vode prekriju,"},{"v":20,"t":"spustit ću te s onima koji su sišli u grob, k narodu pradavnom, i smjestit ću te u najdublje zemljine predjele, u vječnu samoću, s onima što u grob siđoše, da se više ne vratiš u zemlju živih."},{"v":21,"t":"Pretvorit ću te u užas i više te neće biti. Tražit će te, ali te više nikad neće naći!' - riječ je Jahve Gospoda.”"}]},"27":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“A ti sine čovječji, udari u tužaljku nad Tirom"},{"v":3,"t":"i reci Tiru što leži na ulazu u more i trguje s narodima bezbrojnih otoka: 'Ovako govori Jahve Gospod: Tire što govoraše: Ja sam lađa prekrasna, izvanredne ljepote."},{"v":4,"t":"Tvoje međe sežu u more duboko, graditelji tvoji besprimjerno te lijepa načiniše."},{"v":5,"t":"Od senirskih čempresa oplate ti sagradiše, cedar libanonski uzeše, jarbole ti podigoše;"},{"v":6,"t":"od bašanskih hrastova istesaše ti vesla, od bjelokosti i šimšira s kitijimskog otočja palubu ti načiniše!"},{"v":7,"t":"Od vezena lana egipatskog bijahu ti jedra da ti budu zastava! A grimiz i skrlet s eliških otoka staviše ti za krovišta."},{"v":8,"t":"Žitelji Sidona i Arvada bjehu ti veslači, a mudraci tvoji, Tire, bijahu ti kormilari!"},{"v":9,"t":"Starješine gebalske i vještaci popravljahu kvarove tvoje. Sve morske lađe i mornari bijahu tvoji i s tobom trgovahu!"},{"v":10,"t":"Perzijanci, Ludijci i Putijci u tvojoj vojsci bijahu ratnici, u tebi vješahu štitove i kacige; oni ti sjaj davahu."},{"v":11,"t":"Sinovi arvadski s vojnicima na bedemima tvojim uokrug čuvahu ti kule. O zidove ti uokolo štitove vješahu da uzveličaju jedinstvenu ljepotu tvoju!"},{"v":12,"t":"Zbog bogatstva tvoga golemog čak i Taršiš s tobom trgovaše, plaćajući srebrom i gvožđem, olovom i kositrom trg tvoj."},{"v":13,"t":"Javan i Tubal i Mešek s tobom trgovahu: davahu ljude i suđe mjedeno za trg tvoj."},{"v":14,"t":"Oni iz Bet Togarme davahu konje, trkaće konjiće i mazge."},{"v":15,"t":"I sinovi Dedanovi s tobom trgovahu. Mnogi ti otoci bijahu podložni: plaćahu ti daću u bjelokosti i ebanovini."},{"v":16,"t":"Zbog obilja robe tvoje Edom s tobom trgovaše. Davahu ti za trg dragulje, purpur i vezivo, koralje, rubine i bez;"},{"v":17,"t":"i Judeja i zemlja Izraelova trgovahu s tobom: minitskim žitom, voskom, medom, uljem i balzamom trg tvoj plaćahu!"},{"v":18,"t":"Zbog obilja trga tvojeg, silnoga ti blaga, i Damask s tobom trgovaše za helbonsko vino i saharsku vunu."},{"v":19,"t":"I Dan i Javan iz Uzala za trg tvoj prekaljeno gvožđe mijenjahu, cimet i slatku trsku."},{"v":20,"t":"Dedan s tobom trgovaše prostirkama jahačkim."},{"v":21,"t":"Arapi i kedarski knezovi mijenjahu se s tobom, trg ti plaćajući jaganjcima, jarcima i ovnovima."},{"v":22,"t":"Trgovci iz Šebe i Rame trgovahu s tobom, za trg ti davahu najbolje dragulje i zlato."},{"v":23,"t":"Haran, Kane i Eden, trgovci Šebe, Asirije i Kišmada trgovahu s tobom. Mijenjahu za trg tvoj"},{"v":24,"t":"skupocjene halje, purpurne i vezene plašteve, sagove šarene i užad čvrsto pletenu."},{"v":25,"t":"Taršiške su lađe nakrcane prevozile robu tvoju! Bješe tako puna i teška veoma."},{"v":26,"t":"Na pučinu morsku, na mnoga te mora izvedoše veslači. Istočni te vjetar razbi na pučini morskoj!"},{"v":27,"t":"Tvoje blago i trg ti, rukodjela tvoja, lađari tvoji i krmilari, popravljači pukotina, mjenjači trga tvojeg, svi ratnici na tebi i sve mnoštvo posred tebe potonut će na dno morsko na dan tvoga brodoloma!"},{"v":28,"t":"Na vapaj ti krmilara obale će zadrhtati."},{"v":29,"t":"I sići će s lađa svojih svi veslači, svi lađari i svi krmilari i ostat će na kopnu."},{"v":30,"t":"Za tobom će glasno naricati i kukati gorko. Pepelom će posut glave, i valjat se u prašini;"},{"v":31,"t":"zbog tebe će glave obrijati, kostrijet će pripasati, ojađene duše za tobom naricati, i kukati gorko."},{"v":32,"t":"U žalosti će ti tužbalicu zapjevati, nad tobom će protužiti: 'Koji grad k'o Tir ponosan bješe posred mora?'"},{"v":33,"t":"Jer kad bi on blago iskrcao, mnoge bi narode njima nasitio! Obiljem bogatstva i trga mnoge bi kraljeve zemaljske usrećio."},{"v":34,"t":"A sada te, evo, valovi smrskaše, potonu u dubine morske! Blago tvoje i sva posada potonuše s tobom."},{"v":35,"t":"Svi žitelji otočki zbog tebe se prestraviše. Kraljevi se njini naježiše, glave pokunjiše."},{"v":36,"t":"Trgovci narodÄa zviždahu za tobom, jer ti strašilo posta i nestade zauvijek!'”"}]},"28":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, kaži knezu tirskome: 'Ovako govori Jahve Gospod: Tvoje se srce uzoholi, ti reče: 'Ja sam bog! Na božjem prijestolju sjedim u srcu morskom.' Iako čovjek, a ne Bog, ti srce svoje izjednači s Božjim."},{"v":3,"t":"Bješe, eto, od Daniela mudriji, nijedna ti tajna ne bje skrivena!"},{"v":4,"t":"Mudrošću svojom i razborom nateče bogatstva, riznicu napuni srebrom i zlatom!"},{"v":5,"t":"Mudar li bijaše trgovac, bogatstvo svoje namnoži! Al' ti se s bogatstva srce uzoholi.'"},{"v":6,"t":"Stog ovako govori Jahve Gospod: 'Jer svoje srce s Božjim izjednači,"},{"v":7,"t":"dovest ću, evo, na te tuđince najnasilnije među narodima. Isukat će mačeve na mudrost ti divnu, i ljepotu će ti okaljati,"},{"v":8,"t":"bacit će te u jamu da umreš nasilnijom smrću od onih što umiru na pučini morskoj!"},{"v":9,"t":"Hoćeš li tada pred krvnikom reći: 'Ja sam bog'? Čovjek si, a ne bog, u ruci svojih ubojica."},{"v":10,"t":"Umrijet ćeš smrću neobrezanih od ruke tuđinske! Jer ja, Jahve, rekoh to' - riječ je Jahve Gospoda.”"},{"v":11,"t":"I dođe mi riječ Jahvina:"},{"v":12,"t":"“Sine čovječji, zakukaj tužaljku nad tirskim kraljem. Reci mu: 'Ovako govori Jahve Gospod: Gle, ti bješe uzor savršenstva, pun mudrosti i čudesno lijep!"},{"v":13,"t":"U Edenu, vrtu Božjem, ti življaše, resio te dragulj svaki, sard, topaz i dijamant, krizolit, oniks i jaspis, safir, smaragd i zlato. Načinjeni bjehu bubnjevi i frule, na dan ti rođenja bjehu pripravljeni."},{"v":14,"t":"Postavih te kao raskriljena keruba zaštitnika: bio si na svetoj gori Božjoj, hodio si posred ognjena kamenja."},{"v":15,"t":"Savršen bješe na putima svojim od dana svojega rođenja dok ti se u srcu ne zače opačina."},{"v":16,"t":"Obilno trgujući, napuni se nasiljem i sagriješi. Zato te zbacih s gore Božje, istrgoh te, kerube zaštitniče, isred ognjenoga kamenja."},{"v":17,"t":"Srce ti se uzoholi zbog ljepote tvoje, mudrost svoju odnemari zbog svojega blaga! Na zemlju te bacih i predah te zemaljskim kraljevima da te prezirno gledaju."},{"v":18,"t":"Mnoštvom svog bezakonja, nepoštenim trgovanjem oskvrnu svoja svetišta! Pustih oganj posred tebe da te proždre. Pretvorih te na zemlji u pepeo na oči onih što te motre."},{"v":19,"t":"Svi koji te poznaju među narodima zgroziše se nad tobom! Jer ti strašilo posta, nestade zauvijek.'”"},{"v":20,"t":"I dođe mi riječ Jahvina:"},{"v":21,"t":"“Sine čovječji, okreni lice k Sidonu, prorokuj protiv njega."},{"v":22,"t":"Reci: 'Ovako govori Jahve Gospod: Evo me protiv tebe, Sidone, proslavit ću se usred tebe! I znat će se da sam ja Jahve kada nad njim sud izvršim i svetost svoju pokažem u njemu."},{"v":23,"t":"I poslat ću na nj kugu i krv po ulicama njegovim; i mrtvi će posred njega padati od mača, koji ti odasvud prijeti, i znat će se tada da sam ja Jahve."},{"v":24,"t":"I više neće biti domu Izraelovu trna što ranjava nit' žaoke što razdire među svima uokolo koji ga preziru! I znat će se da sam ja Jahve!'”"},{"v":25,"t":"Ovako govori Jahve Gospod: “A kad skupim sav dom Izraelov između naroda po kojima su razasuti, očitovat ću u njima svoju svetost pred očima narodÄa. I nastanit će se u svojoj zemlji što je dadoh sluzi svome Jakovu."},{"v":26,"t":"I u njoj će živjeti u miru, gradit će domove i saditi vinograde. Živjet će u pouzdanju dok budem izvršivao svoj sud nad svima koji ih naokolo prezirahu. I znat će da sam ja Jahve, Bog njihov.”"}]},"29":{"hr":[{"v":1,"t":"Godine desete, desetoga mjeseca, dvanaestoga dana, dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, okreni lice faraonu, kralju egipatskom, i prorokuj protiv njega i protiv sveg Egipta."},{"v":3,"t":"Govori i reci: 'Ovako govori Jahve Gospod: Evo me protiv tebe, faraone, kralju egipatski, golemi krokodile što ležiš usred rijeka svojih. Ti reče: 'Rijeke su moje, sebi sam ih načinio.'"},{"v":4,"t":"I zato ću ti kuke zarit' u gubicu i sve ribe rijeka tvojih zalijepiti na krljušti tvoje. Izvući ću te isred rijeka tvojih sa svim ribama rijeka tvojih zalijepljenim na tvoje krljušti."},{"v":5,"t":"Bacit ću u pustinju tebe i sve ribe iz rijeka tvojih. Na tlo ćeš poljsko pasti, nitko te neće podić' ni sahraniti, zvijerima zemaljskim i nebeskim pticama dat ću te za hranu!"},{"v":6,"t":"I znat će svi stanovnici Egipta da sam ja Jahve. Jer ti bješe trska za oslonac domu Izraelovu!"},{"v":7,"t":"Kad te u ruku uhvatiše, ti se slomi i rane im otvori; a kad se na te osloniše, ti prepuče i bedra im sva izrani.'"},{"v":8,"t":"Stog ovako govori Jahve Gospod: 'Gle, dovest ću mač svoj na te, istrijebit ću iz tebe i ljude i stoku!"},{"v":9,"t":"Sva će zemlja egipatska pustoš biti i razvalina, i oni će znati da sam ja Jahve!' Jer ti reče: 'Rijeka je moja, sebi je načinih.'"},{"v":10,"t":"'Zato evo me na te i na rijeke tvoje da pretvorim zemlju egipatsku u pustinju i pustoš od Migdola do Sevana i do granice etiopske!"},{"v":11,"t":"Neće njome više prolaziti noga ljudska ni noga životinjska, ostat će nenaseljena četrdeset godina."},{"v":12,"t":"Od zemlje ću egipatske načiniti pustoš sred zemalja opustošenih, a gradovi njezini bit će četrdeset godina ruševine među razvaljenim gradovima. I raspršit ću Egipćane među narode i rasijat ću ih po zemljama.'"},{"v":13,"t":"Jer, ovako govori Jahve Gospod: 'Kad mine četrdeset godina, sakupit ću opet sve Egipćane između naroda kamo bijahu raspršeni."},{"v":14,"t":"Vratit ću izgnanike egipatske, vratit ću ih opet u zemlju Patros, domovinu njihovu, da osnuju ondje slabo kraljevstvo."},{"v":15,"t":"Ono će biti najmanje od svih kraljevstava, da se više nikad ne digne nad druge narode. Smanjit ću ga da više nikad ne podjarmi drugih naroda"},{"v":16,"t":"i da više ne bude uzdanje domu Izraelovu. Nek' mu u pamet doziva grijehe koje bijaše počinio okrećući se za njima. I oni će spoznati da sam ja Jahve.'”"},{"v":17,"t":"Godine dvadeset i sedme, prvoga dana prvoga mjeseca, dođe mi riječ Jahvina:"},{"v":18,"t":"“Sine čovječji, kralj babilonski Nabukodonozor krenu s vojskom na velik pohod protiv grada Tira. I svaka glava ogolje i svako se rame odadrije. Ali ni on ni vojska mu ne imahu nikakve dobiti od toga što krenuše na Tir."},{"v":19,"t":"Stoga ovako govori Jahve Gospod: 'Gle, predat ću Nabukodonozoru, kralju babilonskome, zemlju egipatsku. Odnijet će joj blago, nagrabiti plijena i opljačkati je. To će biti plaća vojsci njegovoj."},{"v":20,"t":"Za trud što na Tir krenu dat ću mu svu zemlju egipatsku, jer za me bijaše radio' - riječ je Jahve Gospoda."},{"v":21,"t":"'U onaj ću dan učiniti da izraste rog domu Izraelovu, a tebi ću usta otvoriti među njima. I znat će da sam ja Jahve.'”"}]},"30":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, prorokuj i reci: 'Ovako govori Jahve Gospod: Kukajte: 'Jao dana!'"},{"v":3,"t":"Jer se bliži dan, bliži se dan Jahvin! Dan oblačan, vrijeme narodima određeno."},{"v":4,"t":"I mač će ući u Egipat, a strah će ophrvati Etiopiju kad mrtvi stanu padati po Egiptu i kad se razgrabi njegovo blago te kad mu temelje sve sruše."},{"v":5,"t":"Kuš, Put i Lud, sva Arabija i Libija, i sinovi zemlje Krete s njima od mača će izginuti'!"},{"v":6,"t":"Ovako govori Jahve Gospod: 'Past će koji podupiru Egipat i srozat će se ponos njegove moći. Od Migdola do Sevana sve će u njemu od mača pasti - riječ je Jahve Gospoda."},{"v":7,"t":"On će biti pustoš među opustošenim zemljama, a njegovi gradovi ruševine među razrušenim gradovima."},{"v":8,"t":"I znat će da sam ja Jahve kad zapalim svoj oganj u Egiptu i zatrem sve pomagače njegove."},{"v":9,"t":"U onaj će dan glasnici od mene na lađama isploviti da zastraše bezbrižnu Etiopiju. I strah će je ophrvati u dan egipatski. Jer, evo, bliži se!'"},{"v":10,"t":"Ovako govori Jahve Gospod: 'Uništit ću mnoštvo egipatsko rukom Nabukodonozora, kralja babilonskoga!"},{"v":11,"t":"On i njegov narod s njime - najokrutniji među narodima - bit će dovedeni da zemlju zatru. I oni će isukati mač na Egipat i svu će mu zemlju truplima ispuniti."},{"v":12,"t":"A ja ću isušiti rijeke i zemlju predati u ruke silnicima, opustošit ću zemlju i što je u njoj - rukom tuđinaca. Ja, Jahve, rekoh!'"},{"v":13,"t":"Ovako govori Jahve Gospod: 'Razorit ću kumire i ništavila istrijebiti iz Memfisa, i neće više biti knezova u egipatskoj zemlji, a strah ću posijati u zemlji egipatskoj."},{"v":14,"t":"Opustošit ću Patros, zapaliti Soan, izvršiti sud na Tebi."},{"v":15,"t":"Iskalit ću gnjev nad Sinom, tvrđom egipatskom, istrijebit ću mnoštvo u Tebi."},{"v":16,"t":"Zapalit ću oganj pod Egiptom: Sin će uzdrhtati od strave, Teba će biti osvojena, a Memfis u tjeskobi dan za danom."},{"v":17,"t":"Mladići Heliopola i Pi-Beseta od mača će pasti. A oni će biti odvedeni u ropstvo!"},{"v":18,"t":"Nad Tafnisom pomrčat će dan kad ondje slomim jaram egipatski i kad se dokonča ponos moći u njemu! Nad njim će se nadviti oblak, i njegove će kćeri biti odvedene u ropstvo!"},{"v":19,"t":"Tako ću izvršiti sud nad Egiptom, i znat će da sam ja Jahve.'”"},{"v":20,"t":"Godine jedanaeste, prvoga mjeseca, sedmoga dana dođe mi riječ Jahvina:"},{"v":21,"t":"“Sine čovječji, gle, slomih mišicu faraonu, kralju egipatskom! I evo, nisu je ni povili: nisu metnuli lijekove niti su je povojima obavili da je okrijepe kako bi se opet mogla prihvatiti mača."},{"v":22,"t":"Stoga ovako govori Jahve Gospod: 'Evo me protiv faraona, kralja egipatskoga, da mu slomim obje ruke, i zdravu i slomljenu, i da mu mač izbijem iz ruke!"},{"v":23,"t":"Razagnat ću Egipćane među narode i rasijati ih po zemljama!"},{"v":24,"t":"Ojačat ću ruke kralju babilonskom i mač ću svoj staviti u njegovu ruku; a faraonu ću slomiti ruke te će stenjati pred neprijateljem kao ranjenik."},{"v":25,"t":"Da, ojačat ću ruke kralju babilonskom, a ruke će faraonove klonuti. I znat će se da sam ja Jahve kad metnem mač svoj u ruke kralju babilonskom i on ga zavitla nad zemljom egipatskom."},{"v":26,"t":"Raspršit ću Egipćane među narode i rasijati ih po zemljama. I znat će da sam ja Jahve.'”"}]},"31":{"hr":[{"v":1,"t":"Jedanaeste godine, trećega mjeseca, prvoga dana, dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, kaži faraonu, kralju egipatskom, i mnoštvu njegovu: 'Na koga naličiš veličinom svojom?"},{"v":3,"t":"Usporedit ću te, evo, s cedrom libanonskim, lijepih grana, gusta lišća i debla visoka: vrh mu do oblaka seže."},{"v":4,"t":"Voda ga othrani i uzvisi bezdan; rijekama mu svojim nasad oblijevaše, rukave svoje slaše k svem drveću poljskom."},{"v":5,"t":"I zato rastom on nadvisi sve poljsko drveće. Grane mu se namnožiše, hvoje mu se razgranaše od obilne vode što mu dotjecaše;"},{"v":6,"t":"ptice mu nebeske na granama gnijezda savijahu. Ispod hvoja njegovih legoše se divlje zvijeri. A u hladu njegovu svi veliki narodi sjeđahu."},{"v":7,"t":"Lijep on bijaše veličinom i širinom svojih grana; do dubokih voda žilje mu sezaše!"},{"v":8,"t":"Ne bijahu mu ravni ni cedrovi u vrtu Božjem, ni čempresi se ne mogahu usporediti s granama njegovim, a platane ni kao hvoje njegove ne bijahu! Nijedno stablo u vrtu Božjem ne bješe mu po ljepoti ravno."},{"v":9,"t":"Ukrasih ga mnoštvom grana, i zaviđaše mu sve edensko drveće u vrtu Božjem.'"},{"v":10,"t":"Stoga ovako govori Jahve Gospod: 'Jer se s rasta uzoholio što mu vrh do oblaka sezaše i srce mu visina zanese,"},{"v":11,"t":"predadoh ga u ruke najmoćnijemu od svih naroda da učini s njime po zloći njegovoj, i odbacih ga."},{"v":12,"t":"Tuđinci, najokrutniji od naroda, posjekoše ga i oboriše, grane mu padahu po gorama i svim dolinama, hvoje mu se po svim uvalama polomiše, svi se narodi zemlje od njegova hlada udaljiše, ostaviše ga!"},{"v":13,"t":"Na njegovo oboreno stablo sve ptice nebeske sletješe! Među njegovim se granama sve divlje zvijeri nastaniše!"},{"v":14,"t":"Da se rastom svojim nijedno stablo pokraj vode više ne uzvisi i da vrh svoj među oblake ne uzdigne! I da se nijedno stablo koje pije vode u visinu svoju ne uzdaje! Jer su svi predani smrti, bačeni u podzemne krajeve, posred sinova ljudskih, s onima što slaze u jamu!'"},{"v":15,"t":"Ovako govori Jahve Gospod: 'U dan kad on siđe u Podzemlje, u znak žalosti, zatvorih nad njim ponor i zaustavih rijeke njegove. I velike vode presahnuše te sav Libanon zbog njega u tugu zaogrnuh i sve se poljsko drveće zbog njega osuši!"},{"v":16,"t":"Gromotom pada njegova potresoh narode kad ga strmoglavih u Podzemlje s onima što u jamu siđoše! I u podzemnom se kraju utješi sve drveće edensko, najizabranije i najljepše u Libanonu, sve što je vodu ispijalo."},{"v":17,"t":"I ono, mišica njegova, i oni među narodima koji u hladu njegovu sjeđahu, siđoše s njim u Podzemlje, k onima što mačem bijahu probodeni."},{"v":18,"t":"Na koga, dakle, među drvećem edenskim, naličiš svojom moći, slavom i veličinom? A sad si s njima oboren u podzemni kraj i s neobrezanima ležiš među onima što mačem bijahu probodeni. To je faraon i sve njegovo mnoštvo' - riječ je Jahve Gospoda.”"}]},"32":{"hr":[{"v":1,"t":"Godine dvanaeste, dvanaestoga mjeseca, prvoga dana, dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, zaplači nad faraonom, kraljem egipatskim, i kaži mu: 'Laviću naroda, propao si! Ti bješe kao krokodil u vodi, bučio si u rijekama svojim, nogama si vodu mutio, valove joj podizao!'"},{"v":3,"t":"Ovako govori Jahve Gospod: 'Gle, razapet ću mrežu nad tobom sa skupom mnogih naroda: oni će te u mojoj mreži izvući."},{"v":4,"t":"Ostavit će te na zemlji, tresnuti tobom o tlo. Sve ptice nebeske na te ću pustiti i zvijeri zemaljske tobom ću nahraniti!"},{"v":5,"t":"Meso ću ti razbacat' po gorama, doline ću prekriti strvinom tvojom."},{"v":6,"t":"Istekom iz tebe zemlju ću napojiti, krvlju tvojom po gorama, i korita riječna njome napuniti."},{"v":7,"t":"A kada te utrnem, nebesa ću potamniti i zvijezde na njima ugasiti! Oblakom ću sunce zastrijeti, i mjesec svjetlošću neće svijetliti."},{"v":8,"t":"Sva ću svjetlila na nebu zbog tebe utrnuti i mrak ću nad zemljom razastrijeti!' - riječ je Jahve Gospoda."},{"v":9,"t":"'Ucvilit ću srca mnogih naroda kad izgnanike tvoje odvedem u zemlje tebi nepoznate."},{"v":10,"t":"Narode će mnoge strava uhvatiti, a njihovi će se kraljevi nad tobom užasnuti njima naočigled. I na dan pada tvojega svatko će za svoj život neprestano strepiti.'"},{"v":11,"t":"Jer ovako govori Jahve Gospod: 'Mač kralja babilonskoga na te će se spustiti."},{"v":12,"t":"Tvoje ću mnoštvo pobiti mačevima junaka, najljući od svih naroda opustošit će ponos Egipta i sve mnoštvo njegovo zatrijeti."},{"v":13,"t":"Svu ću stoku njegovu uništiti pokraj voda obilnih. Ljudska ih noga više neće gaziti niti će ih životinjski papak mutiti."},{"v":14,"t":"Onda ću im vode opet stišati i učinit ću da im rijeke kao ulje teku!' - riječ je Jahve Gospoda."},{"v":15,"t":"'Kad zemlju egipatsku opustošim, kad bude opljačkano što je na njoj, kad udarim sve žitelje njezine, znat će da sam ja Jahve."},{"v":16,"t":"Tužaljka je to koja će se naricati. Naricat će je kćeri naroda. Naricat će je nad Egiptom i nad svim njegovim mnoštvom' - riječ je Jahve Gospoda.”"},{"v":17,"t":"Godine dvanaeste, prvoga mjeseca, petnaestoga dana, dođe mi riječ Jahvina:"},{"v":18,"t":"“Sine čovječji, nariči za egipatskim mnoštvom, gurni ga, njega i kćeri naroda slavnih, u podzemni kraj, k onima što siđoše u jamu."},{"v":19,"t":"Od koga si bolji? Siđi i počini s neobrezanima."},{"v":20,"t":"Oni će pasti među one što ih mač pokosi. Ležaj će dobiti sa svim mnoštvom."},{"v":21,"t":"Najhrabriji junaci govorit će mu iz srca Podzemlja: 'Ti i pomoćnici tvoji siđite i počinite s neobrezanima, mačem pokošenima!'"},{"v":22,"t":"Ondje je i Asirac i sva njegova gomila oko groba njegova - svi pobijeni, mačem pokošeni."},{"v":23,"t":"Grobovi im leže na dnu jame i sva mu je gomila oko grobova njegova - svi, nekoć užas u zemlji živih, sada pobijeni, mačem pokošeni."},{"v":24,"t":"Ondje Elam i sve mnoštvo njegovo oko groba njegova - svi pobijeni, mačem pokošeni, neobrezani u podzemni kraj mrtvih siđoše: nekoć užas u zemlji živih, snose sad sramotu svoju s onima što u jamu siđoše."},{"v":25,"t":"Usred pobijenih ležaj smjestiše njemu i mnoštvu oko groba njegova - sve neobrezani, mačem probodeni: nekoć užas u zemlji živih, snose sad sramotu svoju s onima što u jamu siđoše, među pobijene položeni."},{"v":26,"t":"Ondje je Mešek i Tubal i sve mnoštvo njegovo, s grobovima oko groba njegova - svi neobrezani, mačem probodeni, nekoć užas u zemlji živih."},{"v":27,"t":"Ne leže s junacima davno palima, u Podzemlje siđoše s oružjem, s mačem pod glavom i sa štitom na kostima, jer bijahu užas junacima u zemlji živih."},{"v":28,"t":"I ti ćeš ležati usred neobrezanih, mačem pokošenih."},{"v":29,"t":"Ondje je Edom i svi njegovi kraljevi i knezovi: unatoč svojemu junaštvu, i oni leže zajedno s onima što su mačem pokošeni, s neobrezanima, s onima koji u jamu siđoše."},{"v":30,"t":"Ondje su knezovi sjevera i svi Sidonci, i oni siđoše među probodene. Unatoč užasu svojega junaštva, leže neobrezani, s mačem probodenima, snoseći svoju sramotu s onima što u jamu siđoše."},{"v":31,"t":"Vidjet će ih faraon i utješit će se zbog svog mnoštva - faraon i sva vojska njegova mačem pokošena, riječ je Jahve Gospoda!"},{"v":32,"t":"Jer je zadavao strah u zemlji živih, faraon i sve mnoštvo njegovo leže s neobrezanima, s mačem pokošenima - riječ je Jahve Gospoda.”"}]},"33":{"hr":[{"v":1,"t":"Dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, govori sinovima naroda svojega! Reci: 'Ako ja na neku zemlju dovedem mač, a narod te zemlje uzme jednoga između sebe i postavi ga za stražara,"},{"v":3,"t":"a on - videći da mač dolazi na zemlju - zatrubi u rog i opomene sav narod:"},{"v":4,"t":"ako se tada onaj koji čuje glas roga ne da opomenuti te mač dođe i pogubi ga - krv njegova past će na glavu njegovu:"},{"v":5,"t":"jer, čuo je glas roga, ali se ne dade opomenuti - krv njegova past će na njega. Da se dao opomenuti, spasio bi život."},{"v":6,"t":"A opet, ako stražar - videći da mač dolazi na zemlju - ne zatrubi u rog i ne opomene narod te mač dođe i pogubi koga od njih: taj je, doduše, poginuo zbog svoga grijeha, ali ću ja krv njegovu tražiti iz stražarove ruke.'"},{"v":7,"t":"I tebe sam, sine čovječji, postavio za stražara domu Izraelovu: kad čuješ riječ iz mojih usta, opomeni ih u moje ime."},{"v":8,"t":"Reknem li bezbožniku: 'Bezbožniče, umrijet ćeš!' - a ti ne progovoriš i ne opomeneš bezbožnika da se vrati od svojega zloga puta, bezbožnik će umrijeti zbog svojega grijeha, ali krv njegovu tražit ću iz tvoje ruke."},{"v":9,"t":"Ali ako bezbožnika opomeneš da se vrati od svojega zloga puta, a on se ne vrati sa svojega puta: on će umrijeti zbog svojega grijeha, a ti si spasio život svoj."},{"v":10,"t":"Sine čovječji, reci domu Izraelovu: Vi govorite: 'Prijestupi i grijesi naši pritišću nas i zbog njih propadamo! I da još živimo?'"},{"v":11,"t":"Odgovori im: 'Života mi moga - riječ je Jahve Gospoda - nije meni do smrti bezbožnikove, nego da se odvrati od zloga puta svojega i da živi! Obratite se, dakle, obratite od zloga puta svojega! Zašto da umrete, dome Izraelov!'"},{"v":12,"t":"Sine čovječji, reci sinovima naroda svoga: 'Pravednika neće izbaviti pravednost njegova u dan kad sagriješi niti će bezbožnik stradati zbog svoje bezbožnosti u dan kad se od nje odvrati, kao što ni pravednik neće moći ostati na životu u dan kad sagriješi."},{"v":13,"t":"Reknem li ja prevedniku: 'Živjet ćeš!' a on se pouzda u svoju pravednost i stane činiti nepravdu, zaboravit ću svu njegovu pravednost, i on će umrijeti zbog nepravde što je počini!"},{"v":14,"t":"A reknem li bezbožniku: 'Umrijet ćeš!' a on se odvrati od grijeha svojega i stane raditi po zakonu i pravdi,"},{"v":15,"t":"vrati zalog, plati oteto i stane živjeti po zakonima života, ne čineći bezakonja - živjet će, neće umrijeti!"},{"v":16,"t":"I svi grijesi njegovi što ih bijaše počinio bit će mu zaboravljeni. Radi po zakonu i pravdi, živjet će!'"},{"v":17,"t":"Ali sinovi naroda tvoga govore: 'Jahvin put nije pravedan!' Njihov put nije pravedan!"},{"v":18,"t":"Ako se pravednik odvrati od svoje pravednosti i stane činiti nepravdu, on će stoga umrijeti."},{"v":19,"t":"A ako se bezbožnik odvrati od svoje bezbožnosti i stane raditi po zakonu i pravdi, on će zbog toga živjeti."},{"v":20,"t":"A vi velite: 'Jahvin put nije pravedan!' Svakome ću od vas suditi prema putovima njegovim, dome Izraelov!”"},{"v":21,"t":"Godine dvanaeste, desetoga mjeseca, petoga dana našeg izgnanstva, dođe k meni bjegunac iz Jeruzalema i reče: “Pade grad!”"},{"v":22,"t":"Ruka se Jahvina spustila na me uveče, prije dolaska toga bjegunca, i otvorila mi usta prije negoli on dođe k meni ujutro! Otvoriše mi se, dakle, usta i ja više ne bijah nijem."},{"v":23,"t":"I dođe mi riječ Jahvina:"},{"v":24,"t":"“Sine čovječji, oni koji žive u ovim ruševinama zemlje Izraelove govore: 'Jedan bijaše Abraham i baštini ovu zemlju, a nas je mnogo - nama je zemlja dana u posjed!'"},{"v":25,"t":"Stoga im reci: 'Ovako govori Jahve Gospod: Vi blagujete po gorama, oči podižete kumirima svojim, krv prolijevate - i još da posjedujete ovu zemlju?"},{"v":26,"t":"Na svoj se mač oslanjate, činite gadosti, oskvrnjujete ženu bližnjega - i još da posjedujete ovu zemlju?'"},{"v":27,"t":"Ovo im reci: 'Ovako govori Jahve Gospod: Života mi moga, oni koji su u ruševinama od mača će pasti; one koji su u polju dat ću zvijerima da ih proždru; a koji su u utvrdama i po pećinama od kuge će poginuti!"},{"v":28,"t":"Tako ću zemlju ovu razoriti i opustošiti i nestat će zauvijek drskoga njezina ponosa. Opustjet će gore Izraelove i nitko više neće njima prolaziti."},{"v":29,"t":"I znat će da sam ja Jahve kad zemlju njihovu razorim i opustošim zbog svih gadosti što ih počiniše.'"},{"v":30,"t":"A o tebi, sine čovječji, sinovi naroda tvoga kazuju uza zidove i na kućnim vratima i govore jedan drugom: 'Hajde da čujemo kakva je to riječ došla od Jahve!'"},{"v":31,"t":"I hrle k tebi kao na zbor narodni; i narod moj sjeda preda te i sluša tvoje riječi, ali ih ne izvršuje: naslađuju se njima u ustima, a srce im ide za nepravednim dobitkom."},{"v":32,"t":"I gle, ti si za njih kao slatka pjesma uz glazbu otpjevana glasom umilnim: riječi ti slušaju, ali ih ne izvršuju."},{"v":33,"t":"Ali kad sve ovo dođe - gle, već dolazi - znat će da prorok bijaše među njima!”"}]},"34":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, prorokuj protiv Izraelovih pastira, prorokuj im i reci: 'Ovako govori Jahve Gospod: Jao pastirima Izraelovim koji napasaju sami sebe! Ne moraju li pastiri napasati stado?"},{"v":3,"t":"Mlijekom se hranite, vunom odijevate, ovnove tovne koljete, a stada ne pasete."},{"v":4,"t":"Nemoćnih ne krijepite, bolesnih ne liječite, ranjenih ne povijate, zalutalih natrag ne dovodite, izgubljenih ne tražite, nego nasilno i okrutno njima gospodarite."},{"v":5,"t":"I tako se ovce raspršiše nemajuć' pastira, i raspršene postadoše plijen zvijerima."},{"v":6,"t":"Ovce lutaju po svim gorama i visokim bregovima; po svoj su zemlji raspršene ovce moje i nitko za njih ne pita, nikoga nema da ih traži.'"},{"v":7,"t":"Zato, pastiri, čujte riječ Jahvinu:"},{"v":8,"t":"'Tako mi života, riječ je Jahve Gospoda: zato što ovce moje postadoše plijen i hrana zvijerima, nemajuć' pastira, dok pastiri moji ovaca mojih ne traže nego sami sebe pasu, a ne pasu stada mojega -"},{"v":9,"t":"zato, pastiri, čujte riječ Jahvinu:"},{"v":10,"t":"Ovako govori Jahve Gospod: 'Evo me na pastire! Ovce svoje tražit ću iz ruku njihovih i neću im dati da mi više stado pasu ni da sami sebe pasu: istrgnut ću ovce iz usta njihovih, neće im više biti hrana.'"},{"v":11,"t":"Jer ovako govori Jahve Gospod: 'Evo me, sam ću potražiti ovce svoje i sam ću ih pasti!"},{"v":12,"t":"Kao što se pastir brine za ovce svoje kad se nađe uza stado raspršeno, i ja ću se pobrinuti za svoje ovce i skupit' ih iz svih mjesta u koje se raspršiše u dan oblaka i mraka."},{"v":13,"t":"Izvest ću ih iz naroda, skupit ću ih iz zemalja i dovesti ih u zemlju njihovu da ih pasem na gorama izraelskim, po svim dolinama i travnjacima."},{"v":14,"t":"Past ću ih na izvrsnim pašama, ovčinjaci će im biti na visokim gorama izraelskim; ondje će počivati u dobrim ovčinjacima i past će na sočnim pašama, po gorama izraelskim."},{"v":15,"t":"Sam ću pasti ovce svoje i sam ću im dati počinka - riječ je Jahve Gospoda."},{"v":16,"t":"Potražit ću izgubljenu, dovesti natrag zalutalu, povit ću ranjenu i okrijepiti nemoćnu, bdjeti nad pretilom i jakom - past ću ih pravedno.'"},{"v":17,"t":"A vama, ovce moje, ovako govori Jahve Gospod: 'Evo me da sudim između ovce i ovce, između ovnova i jaraca!"},{"v":18,"t":"Zar vam je malo pasti na dobroj paši te ostatak paše nogama gazite? Malo vam je piti bistru vodu te ostatak nogama mutite?"},{"v":19,"t":"A moje ovce moraju pasti što vi nogama izgaziste, piti što vi nogama zamutiste.'"},{"v":20,"t":"Stoga ovako govori Jahve Gospod: 'Evo me da sudim između ovce pretile i mršave!"},{"v":21,"t":"Jer bokovima i plećima, bodući rogovima, slabe ovce guraste dok ih ne izguraste."},{"v":22,"t":"Ja ću izbaviti ovce svoje da više ne budu plijenom i sudit ću između ovce i ovce."},{"v":23,"t":"Postavit ću im jednoga pastira koji će ih pasti, slugu svoga Davida: on će ih sam pasti i bit će im pastir,"},{"v":24,"t":"a ja, Jahve, bit ću njihov Bog, i moj sluga David bit će im knez. Ja, Jahve, rekoh!"},{"v":25,"t":"I sklopit ću s njima Savez mira i uklonit ću iz zemlje sve divlje zvijeri, i živjet će mirno u pustinji i spavati po šumama."},{"v":26,"t":"Njih i sve oko brda svojega učinit ću blagoslovom i dat ću im na vrijeme kišu, i bit će to kiša blagoslova."},{"v":27,"t":"I drveće će poljsko donositi plodove, a zemlja će dati rod svoj. I oni će mirno živjeti u svojoj zemlji i znat će da sam ja Jahve kad slomim palice jarma njihova i kad ih izbavim iz ruku onih što ih podjarmiše."},{"v":28,"t":"I neće više biti plijenom narodima, i zvijeri ih više neće žderati, nego će mirno živjeti i nitko ih neće plašiti."},{"v":29,"t":"I učinit ću da im probuja slavni nasad, i glad ih više neće zatirati, u zemlji više neće podnositi rug narodÄa."},{"v":30,"t":"I znat će da sam ja, Jahve, Bog njihov, s njima i da su oni, dom Izraelov, narod moj - riječ je Jahve Gospoda."},{"v":31,"t":"Vi, ovce moje, vi ste stado paše moje, a ja sam Bog vaš' - riječ je Jahve Gospoda.”"}]},"35":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, okreni lice k Seirskoj gori i prorokuj protiv nje!"},{"v":3,"t":"Reci joj: 'Ovako govori Jahve Gospod: Evo me na te, Goro seirska! Ruku ću podići na te i pretvoriti te u pustoš i pustinju."},{"v":4,"t":"Gradove ću tvoje razvaliti i postat ćeš pustinjom. I znat ćeš da sam ja Jahve!"},{"v":5,"t":"Vječnu si mržnju gojila i maču predavala sinove Izraelove kad bi ih nesreća pogodila i kad bi im kucnuo čas posljednjega grijeha."},{"v":6,"t":"Zato, života mi moga - riječ je Jahve Gospoda - krvi ću te predati i krv će te progoniti: od krvi nisi prezala, krv će te progoniti!"},{"v":7,"t":"Od Gore seirske učinit ću pustoš i pustinju, istrijebit ću iz nje polaznika i povratnika."},{"v":8,"t":"Gore njezine napunit ću truplima: po tvojim brežuljcima, po tvojim dolinama i po tvojim uvalama padat će mačem pokošeni."},{"v":9,"t":"Učinit ću od tebe vječnu pustinju, gradovi se tvoji neće napučiti. I znat ćete da sam ja Jahve!'"},{"v":10,"t":"Ti reče: 'Ova dva naroda i ove dvije zemlje bit će moji; mi ćemo ih zaposjesti, ako i jest Jahve bio ondje!'"},{"v":11,"t":"'Zato, života mi moga - riječ je Jahve Gospoda - postupit ću s tobom prema gnjevu i ljubomori s kojom ti postupi u svojoj mržnji s njima! Upoznat ćeš me po tome kako ću ti suditi!"},{"v":12,"t":"I znat ćeš da sam ja, Jahve, čuo sve tvoje hule što ih izreče na gore Izraelove govoreći: 'Opustješe, nama su dane za hranu!'"},{"v":13,"t":"Razmetali ste se, protiv mene govorili i gomilali protiv mene riječi; čuo sam ja!'"},{"v":14,"t":"Ovako govori Jahve Gospod: 'Na radost sve zemlje, od tebe ću učiniti pustoš."},{"v":15,"t":"Kako si se ti radovala što opustje baština doma Izraelova, tako ću učiniti s tobom: opustjet ćeš, Goro seirska, a s tobom i sav Edom! I znat će se da sam ja Jahve!”"}]},"36":{"hr":[{"v":1,"t":"Sine čovječji, prorokuj gorama Izraelovim i reci: “O gore Izraelove, čujte riječ Jahvinu:"},{"v":2,"t":"Ovako govori Jahve Gospod: Neprijatelji vaši govore o vama: 'Ha! Ha! Visine vječne postat će naš posjed!'"},{"v":3,"t":"I zato prorokuj i reci: 'Ovako govori Jahve Gospod: Sa svih vas strana pustoše i plijene da budete posjed ostalim narodima i na jezike dođoste svjetini klevetničkoj."},{"v":4,"t":"Zato, gore Izraelove, čujte riječ Jahvinu! Ovako govori Jahve Gospod gorama i brežuljcima, uvalama i dolinama, opustošenim razvalinama i napuštenim gradovima koji postadoše plijen i ruglo ostalim narodima uokolo -"},{"v":5,"t":"ovako, dakle, govori Jahve Gospod: Zaista sam govorio o ognju ljubomore svoje protiv ostalih naroda, protiv sveg Edoma, koji s radošću u srcu i s mržnjom u duši sebi prisvoji u posjed zemlju moju da je oplijeni i opljačka.'"},{"v":6,"t":"Zato prorokuj o zemlji Izraelovoj! Reci gorama i brežuljcima, uvalama i dolinama: 'Ovako govori Jahve Gospod! Evo, govorim u ljubomori i jarosti jer moradoste podnositi rug naroda.'"},{"v":7,"t":"Zato ovako govori Jahve Gospod: 'Evo, dižem ruku i kunem se: narodi koji su oko vas snosit će sami svoju sramotu!"},{"v":8,"t":"A vi, gore Izraelove, razgranajte se i donesite rod narodu koji će skoro doći."},{"v":9,"t":"Jer, evo me k vama! K vama se okrenuh, i gajit ću vas i zasijati!"},{"v":10,"t":"Razmnožit ću ljude po vama - sav dom Izraelov - gradove vam napučiti, razvaline vaše opet podići!"},{"v":11,"t":"Razmnožit ću po vama ljude i stoku, oni će se namnožiti i naploditi - te ću vas napučiti kao nekoć i obasuti vas dobrima više nego prije! I znat ćete da sam ja Jahve!"},{"v":12,"t":"Dovest ću k vama ljude, narod svoj, Izraela, i zaposjest će te i bit ćeš im baština i nećeš im više djecu otimati.'”"},{"v":13,"t":"Ovako govori Jahve Gospod: “A što se o tebi govori: 'Ti si zemlja koja ljude proždire i svojem narodu djecu otima' -"},{"v":14,"t":"ti više nećeš ljude proždirati ni narodu svome djece otimati - riječ je Jahve Gospoda."},{"v":15,"t":"Ne dam da više slušaš rug pogana, ne dam da više budeš na sramotu narodima: nećeš više narodu svojem djece otimati” - riječ je Jahve Gospoda."},{"v":16,"t":"Dođe mi riječ Jahvina:"},{"v":17,"t":"“Sine čovječji, kad dom Izraelov još življaše u svojoj zemlji, oskvrnu je svojim nedjelima i svojim putovima. Putovi njihovi bijahu preda mnom kao nečistoća žene nečiste."},{"v":18,"t":"I zato na njih izlih gnjev svoj zbog krvi što je proliše i zbog kumira kojima je oskvrnuše."},{"v":19,"t":"Rasprših ih među narode i rasijah po zemljama. Sudio sam im prema putovima i nedjelima njihovim."},{"v":20,"t":"Ali u narodima među koje dođoše, među svim narodima u koje dospješe, oskvrnjivahu moje sveto ime, jer o njima se govorilo: 'To je Jahvin narod, a morade otići iz zemlje Jahvine!'"},{"v":21,"t":"I meni se sažali moje sveto ime što ga dom Izraelov obeščasti u narodima među koje dođe."},{"v":22,"t":"Reci zato domu Izraelovu: 'Ovako govori Jahve Gospod: Što činim, ne činim radi vas, dome Izraelov, nego radi svetoga imena svojega, koje vi oskvrnuste među narodima u koje dođoste."},{"v":23,"t":"Ja ću posvetiti ime svoje veliko koje vi oskvrnuste posred narodÄa u koje dođoste! I znat će narodi da sam ja Jahve - riječ je Jahve Gospoda - kad na vama, njima naočigled, pokažem svetost svoju."},{"v":24,"t":"Tada ću vas sabrati iz svih naroda i skupiti iz svih zemalja, natrag vas dovesti u vašu zemlju."},{"v":25,"t":"Poškropit ću vas vodom čistom da se očistite. Očistit ću vas od svih vaših nečistoća i od svih kumira vaših."},{"v":26,"t":"Dat ću vam novo srce, nov duh udahnut ću u vas! Izvadit ću iz tijela vašega srce kameno i dat ću vam srce od mesa."},{"v":27,"t":"Duh svoj udahnut ću u vas da hodite po mojim zakonima i da čuvate i vršite moje naredbe."},{"v":28,"t":"I nastanit ćete se u zemlji koju dadoh vašim ocima, i bit ćete moj narod, a ja ću biti vaš Bog."},{"v":29,"t":"Izbavit ću vas od svih vaših nečistoća i dozvat ću žito i umnožiti ga, i nikad vas više neću izvrći gladi."},{"v":30,"t":"Umnožit ću plod drveća i rod njiva da ne podnosite više zbog gladi sramotu među narodima."},{"v":31,"t":"I tada ćete se spomenuti zlih putova i nedjela svojih, i sami ćete sebe omrznuti zbog bezakonja i gadosti svojih."},{"v":32,"t":"A što činim, znajte dobro, ne činim radi vas - riječ je Jahve Gospoda! Postidite se i posramite zbog putova svojih, dome Izraelov!'"},{"v":33,"t":"Ovako govori Jahve Gospod: 'A kad vas očistim od svih bezakonja vaših, napučit ću opet vaše gradove i sagraditi razvaline;"},{"v":34,"t":"opustjela zemlja, nekoć pustinja naočigled svakom prolazniku, bit će opet obrađena."},{"v":35,"t":"Tada će se reći: 'Evo zemlje što bijaše pusta, a postade kao vrt edenski! Gle gradova što bijahu pusti, same razvaline i ruševine, a sada su utvrđeni i napučeni!'"},{"v":36,"t":"I narodi oko vas koji preostanu znat će da ja, Jahve, razvaljeno opet gradim, i što bi opustošeno, opet sadim. Ja, Jahve, rekoh i učinit ću!'"},{"v":37,"t":"Ovako govori Jahve Gospod: Još će ovo moliti dom Izraelov: da im ljudstvo namnožim kao stada."},{"v":38,"t":"Kao svetim stadima, kao stadima blagdanskih dana u Jeruzalemu, gradovi, nekoć razvaline, napučit će se ljudstvom. I znat će da sam ja Jahve.”"}]},"37":{"hr":[{"v":1,"t":"I spusti se na me ruka Jahvina i Jahve me u svojem duhu izvede i postavi usred doline pune kostiju."},{"v":2,"t":"Provede me kroz njih, svuda oko njih, i gle, bijaše ih u dolini veoma mnogo i bijahu sasvim suhe!"},{"v":3,"t":"Reče mi: “Sine čovječji, mogu li ove kosti oživjeti?” Ja odgovorih: “Jahve Gospode, to samo ti znaš!”"},{"v":4,"t":"Tad mi reče: “Prorokuj ovim kostima i reci im: 'O suhe kosti, čujte riječ Jahvinu!'"},{"v":5,"t":"Ovako govori Jahve Gospod ovim kostima: 'Evo, duh ću svoj udahnuti u vas i oživjet ćete!"},{"v":6,"t":"Žilama ću vas ispreplesti, mesom obložiti, kožom vas obaviti i duh svoj udahnuti u vas i oživjet ćete - i znat ćete da sam ja Jahve!'”"},{"v":7,"t":"I ja stadoh prorokovati kao što mi bješe zapovjeđeno. I dok sam prorokovao, nastade šuškanje i pomicanje i kosti se stadoše pribirati."},{"v":8,"t":"Pogledah, i gle, po njima narasle žile i meso; kožom se presvukoše, ali duha još ne bijaše u njima."},{"v":9,"t":"I reče mi: “Prorokuj duhu, sine čovječji, prorokuj i reci: 'Ovako govori Jahve Gospod: Od sva četiri vjetra dođi, duše, i dahni u ova trupla da ožive!'”"},{"v":10,"t":"I stadoh prorokovati kao što mi zapovjedi, i duh uđe u njih i oživješe i stadoše na noge - vojska vrlo, vrlo velika."},{"v":11,"t":"Reče mi: “Sine čovječji, te kosti - to je sav dom Izraelov. Evo, oni vele: 'Usahnuše nam kosti i propade nam nada, pogibosmo!'"},{"v":12,"t":"Zato prorokuj i reci im. 'Ovako govori Jahve Gospod: Ja ću otvoriti vaše grobove, izvesti vas iz vaših grobova, narode moj, i odvesti vas u zemlju Izraelovu!"},{"v":13,"t":"I znat ćete da sam ja Jahve kad otvorim grobove vaše i kad vas izvedem iz vaših grobova, moj narode!"},{"v":14,"t":"I duh svoj udahnut ću u vas da oživite, i dovest ću vas u vašu zemlju, i znat ćete da ja, Jahve govorim i činim' - riječ je Jahve Gospoda.”"},{"v":15,"t":"I dođe mi riječ Jahvina:"},{"v":16,"t":"“Sine čovječji, uzmi drvo i napiši na njemu: 'Juda i sinovi Izraelovi, njegovi saveznici!' Onda uzmi drugo drvo i napiši na njemu: 'Josip - drvo Efrajimovo - i sav dom Izraelov, njegov saveznik.'"},{"v":17,"t":"I sastavi ih u jedno drvo da budu kao jedno u tvojoj ruci!"},{"v":18,"t":"A kad te sinovi tvojega naroda zapitaju: 'Hoćeš li nam objasniti što to znači?' -"},{"v":19,"t":"reci im: 'Ovako govori Jahve Gospod: Evo, uzet ću drvo Josipovo, što je u ruci Efrajimovoj, drvo Josipovo i Izraelovih plemena, njegovih saveznika, i sastavit ću ga s drvetom Judinim te ću od njih načiniti jedno; oba će biti jedno u mojoj ruci.'"},{"v":20,"t":"Oba drveta na koja to napišeš neka ti budu u ruci, njima naočigled."},{"v":21,"t":"I reci im: 'Ovako govori Jahve Gospod: Evo, skupit ću sinove Izraelove iz naroda u koje dođoše, skupit ću ih odasvud i odvesti ih u zemlju njihovu."},{"v":22,"t":"I načinit ću od njih jedan narod u zemlji, u gorama Izraelovim, i bit će im svima jedan kralj, i oni više neće biti dva naroda i neće više biti razdijeljeni na dva kraljevstva."},{"v":23,"t":"I neće se više kaljati svojim kumirima, ni svojim grozotama, ni opačinama. Izbavit ću ih od svih njihovih nevjera kojima zgriješiše i očistit ću ih, i oni će biti moj narod, a ja njihov Bog."},{"v":24,"t":"I sluga moj David bit će im kralj i svima će im biti jedan pastir. Živjet će po mojim zakonima, čuvajući i vršeći moje naredbe."},{"v":25,"t":"Boravit će u zemlji koju dadoh sluzi svome Jakovu, u kojoj življahu oci vaši: u njoj će stanovati oni i njihovi sinovi, i sinovi sinova njihovih dovijeka. I moj sluga David bit će im knez dovijeka."},{"v":26,"t":"Sklopit ću s njima savez mira; bit će to Savez vječan s njima. Utvrdit ću ih i razmnožiti i postavit ću Svetište svoje zauvijek među njih."},{"v":27,"t":"Moj će Šator biti među njima i ja ću biti Bog njihov, a oni narod moj!"},{"v":28,"t":"I kad Svetište moje bude zauvijek među njima, znat će svi narodi da sam ja Jahve, koji posvećujem Izraela.'”"}]},"38":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Sine čovječji, okreni lice ka Gogu, u zemlji Magogu, velikom knezu Mešeka i Tubala, prorokuj protiv njega."},{"v":3,"t":"Reci: 'Ovako govori Jahve Gospod: Evo me na te, Gože, veliki kneže Mešeka i Tubala!"},{"v":4,"t":"Namamit ću te i metnut ću ti žvale u čeljusti, izvest ću tebe i svu tvoju vojsku - konje i konjanike, silno mnoštvo u potpunoj opremi - sve u oklopima i sa štitovima, sve vične maču."},{"v":5,"t":"S njima je i Perzija, Etiopija i Put - svi sa štitovima i pod kacigama;"},{"v":6,"t":"zatim Gomer i sve čete njegove, Bet Togarma s krajnjega sjevera i sve čete njezine - silan narod s tobom!"},{"v":7,"t":"Dobro se spremi ti i sve mnoštvo što se oko tebe skupilo i stani mu na čelo!"},{"v":8,"t":"Poslije mnogo dana dobit ćeš zapovijed; poslije mnogo godina navalit ćeš na zemlju, izbavljenu od mača i skupljenu iz mojih naroda, na gore Izraelove, nekoć zadugo puste: otkako ih izvedoh iz naroda, svi spokojno žive."},{"v":9,"t":"Dići ćeš se, doći kao nevrijeme, kao oblak što prekrije zemlju, ti i tvoje čete, a s vama sila naroda!'"},{"v":10,"t":"Ovako govori Jahve Gospod: 'U onaj će ti se dan misli rojiti u srcu i skovat ćeš zao naum."},{"v":11,"t":"Reći ćeš: 'Hajde da se dignem na zemlju nebranjenu, da navalim na miran narod koji spokojno živi bez zidina i bez prijevornica i bez vrata:"},{"v":12,"t":"pa da se plijena naplijenim i pljačke napljačkam - da ruku stavim na razvaline opet napučene i na narod iz narÄodÄa sakupljen, koji se bavi stadima i imanjem i živi u središtu zemlje.'"},{"v":13,"t":"Šeba, Dedan i trgovci taršiški i svi njihovi lavići pitat će te: 'Zar zato dolaziš plijeniti? I zar si radi pljačke toliku gomilu skupio da odneseš srebro i zlato, da otmeš stoku i imanje i da se plijena velikoga naplijeniš?'"},{"v":14,"t":"Zato prorokuj, sine čovječji, i reci Gogu: 'Ovako govori Jahve Gospod: U onaj dan kad narod moj izraelski bude spokojno živio, ti ćeš se podići!"},{"v":15,"t":"Doći ćeš iz svoga sjedišta, s krajnjega sjevera, ti i s tobom mnogo naroda, sve samih konjanika, silno mnoštvo, golema vojska."},{"v":16,"t":"Navalit ćeš na Izraela, narod moj, kao oblak kad pokrije zemlju. U posljednje dane dovest ću te na svoju zemlju da me narodi upoznaju, kad na tebi, Gože, njima naočigled, pokažem svetost svoju.'"},{"v":17,"t":"Ovako govori Jahve Gospod: 'Nisi li ti onaj o kome sam govorio, u davne dane, preko slugu svojih, proroka Izraelovih, koji u ono vrijeme prorokovaše da ću te na njih dovesti?"},{"v":18,"t":"U onaj dan kad Gog navali na zemlju Izraelovu - riječ je Jahve Gospoda - gnjev će mi iz nosa planuti."},{"v":19,"t":"U ljubomori svojoj i u ognju jarosti svoje odlučih: U onaj dan bit će silan potres u zemlji Izraelovoj."},{"v":20,"t":"I trest će se poda mnom ribe morske i ptice nebeske, poljske zvijeri i gmazovi što gmižu po zemlji i svi ljudi što žive na njoj. Planine će se razvaliti, vrleti popadati i sve se zidine porušiti!"},{"v":21,"t":"I po svim svojim gorama pozvat ću na njega mač - riječ je Jahve Gospoda - s mačem će se brat na brata dići!"},{"v":22,"t":"Sudit ću mu kugom i krvlju. I spustit ću silan pljusak, i kamenje tÓuče, oganj i sumpor na nj, na njegove čete i na mnogi narod koji bude s njime."},{"v":23,"t":"I uzveličat ću se, posvetiti i objaviti pred svim narodima, i znat će da sam ja Jahve.'"}]},"39":{"hr":[{"v":1,"t":"Sine čovječji, prorokuj protiv Goga i reci: 'Ovako govori Jahve Gospod: Evo me na te, Gože, veliki kneže Mešeka i Tubala!"},{"v":2,"t":"Namamit ću te i povesti, podići te s krajnjega sjevera i dovesti na gore Izraelove."},{"v":3,"t":"Izbit ću ti luk iz lijeve ruke i prosuti strijele iz tvoje desnice."},{"v":4,"t":"Na gorama ćeš Izraelovim pasti, ti i sve tvoje čete i narodi koji budu s tobom: pticama grabljivicama, svemu krilatom, i zvijerima dadoh te za hranu."},{"v":5,"t":"Na otvorenom ćeš polju pasti, jer ja tako rekoh - riječ je Jahve Gospoda."},{"v":6,"t":"Poslat ću oganj na Magog i na sve koji spokojno žive na otocima - i znat će da sam ja Jahve."},{"v":7,"t":"A svoje sveto ime objavit ću posred naroda svoga izraelskoga i neću dati da se više oskvrnjuje moje sveto ime! I znat će svi narodi da sam ja, Jahve, Svetac Izraelov."},{"v":8,"t":"Evo dolazi i biva - riječ je Jahve Gospoda! To je dan o kojem sam govorio!"},{"v":9,"t":"Izići će stanovnici izraelskih gradova, naložiti vatru i spaliti oružje, štitove, štitiće, lukove i strelice, koplja i sulice - ložit će njima vatru sedam godina."},{"v":10,"t":"Neće nositi drva iz polja ni sjeći u šumama, nego će vatru oružjem ložiti. I oplijenit će one koji su njih plijenili, opljačkati one koji su njih pljačkali - riječ je Jahve Gospoda."},{"v":11,"t":"U onaj ću dan dati Gogu za grob glasovito mjesto u Izraelu: dolinu Abarim, istočno od Mora, koja zatvara put prolaznicima; ondje će pokopati Goga i sve njegovo mnoštvo. I dolina će se prozvati Hamon-Gog."},{"v":12,"t":"I ukopavat će ih dom Izraelov, sedam mjeseci, da očisti svu zemlju;"},{"v":13,"t":"pokapat će ih sav narod zemlje. I bit će im slavan dan u koji se proslavim, riječ je Jahve Gospoda."},{"v":14,"t":"Izabrat će ljude da neprestano prolaze zemljom pa da s prolaznicima pokapaju one koji preostaše po zemlji, da je tako očiste."},{"v":15,"t":"I kad koji, prolazeći zemljom, vidi ljudske kosti, podignut će kraj njih nadgrobnik dok ih grobari ne ukopaju u dolini Hamon-Gog."},{"v":16,"t":"Hamona je ime i gradu. I tako će očistiti zemlju."},{"v":17,"t":"Sine čovječji, ovako govori Jahve Gospod: Reci pticama, svemu krilatom i svemu zvijerju: skupite se i dođite! Saberite se odasvud na žrtvu moju koju koljem za vas, na veliku gozbu po izraelskim gorama, da se najedete mesa i napijete krvi."},{"v":18,"t":"Najedite se mesa od junaka i napijte se krvi zemaljskih knezova, ovnova, janjaca, jaraca, junaca, ugojene stoke bašanske!"},{"v":19,"t":"Najedite se do sita pretiline i napijte se krvi mojih klanica koje sam vam naklao."},{"v":20,"t":"Nasitite se za mojim stolom konja i konjanika, junaka i ratnika!' - riječ je Jahve Gospoda."},{"v":21,"t":"'Tako ću se proslaviti među narodima, i svi će narodi vidjeti sud koji ću izvršiti i ruku što ću je na njih podići."},{"v":22,"t":"Znat će dom Izraelov da sam ja, Jahve, Bog njihov - od toga dana zauvijek."},{"v":23,"t":"I znat će narodi da dom Izraelov bijaše odveden u ropstvo zbog svojih nedjela: iznevjerio mi se, pa sakrih lice svoje od njih i predadoh ih njihovim neprijateljima u ruke da od mača poginu."},{"v":24,"t":"Postupih s njima po nečistoći njihovoj i nedjelima te sakrih lice svoje od njih.'"},{"v":25,"t":"Stoga ovako govori Jahve Gospod: 'Sad ću vratiti roblje Jakovljevo i pomilovati sav dom Izraelov - ljubomoran na ime svoje sveto,"},{"v":26,"t":"oprostit ću im svu sramotu i nevjeru kojom mi se iznevjeriše dok još spokojno življahu u zemlji i nikoga ne bijaše da ih straši."},{"v":27,"t":"A kad ih dovedem iz naroda i skupim iz zemalja dušmanskih i na njima, naočigled mnogih naroda, svetost svoju pokažem,"},{"v":28,"t":"znat će da sam ja Jahve, Bog njihov, koji ih u izgnanstvo među narode odvedoh i koji ih opet skupljam u njihovu zemlju, ne ostavivši ondje nijednoga od njih."},{"v":29,"t":"I nikada više neću kriti lica od njih, jer ću duh svoj izliti na dom Izraelov' - riječ je Jahve Gospoda.”"}]},"40":{"hr":[{"v":1,"t":"Godine dvadeset i pete za našega izgnanstva, početkom godine, prvoga mjeseca, desetoga dana, a četrnaest godina otkako pade Grad, upravo onoga dana spusti se na me ruka Jahvina."},{"v":2,"t":"I odvede me u božanskom viđenju u zemlju Izraelovu te me postavi na veoma visoku goru: Na njoj, s južne strane, bijaše nešto kao sazidan grad."},{"v":3,"t":"Povede me onamo, i gle: čovjek, sjajan kao mjed, stajaše na vratima, s lanenim užetom i mjeračkom trskom u ruci."},{"v":4,"t":"I taj mi čovjek reče: “Sine čovječji, gledaj svojim očima i slušaj svojim ušima, popamti sve što ću ti pokazati, jer si doveden ovamo da ti pokažem. Objavi domu Izraelovu sve što ovdje vidiš.”"},{"v":5,"t":"I gle, zdanje sve uokolo opasano zidom. Čovjek držaše u ruci mjeračku trsku od šest lakata, a svaki lakat bijaše za jedan dlan duži od običnoga lakta. On izmjeri zdanje. Širina: jedna trska, visina: jedna trska."},{"v":6,"t":"Zatim pođe k vratima što bijahu okrenuta k istoku. Uspe se uza stepenice i izmjeri prag vrata. Širina: jedna trska."},{"v":7,"t":"A svaka klijet jednu trsku dugačka i jednu trsku široka. Između klijeti: pet lakata. Prag vrata sa strane njihova trijema, iznutra, jedna trska."},{"v":8,"t":"Izmjeri trijem vrata iznutra: bijaše osam lakata širok,"},{"v":9,"t":"a njegovi polustupovi dva lakta. Trijem vrata bijaše s nutarnje strane."},{"v":10,"t":"Na svakoj strani istočnih vrata bijahu po tri klijeti. I sve tri bijahu iste mjere. Tako i polustupovi: s obje strane bijahu iste mjere."},{"v":11,"t":"Zatim izmjeri vrata: bijahu deset lakata široka i trinaest lakata visoka."},{"v":12,"t":"Pred klijetima bijaše s jedne i s druge strane ograda od jednog lakta. Svaka klijet: šest lakata s jedne i šest lakata s druge strane."},{"v":13,"t":"A zatim izmjeri vrata od stražnje strane jedne klijeti do stražnje strane nasuprotne klijeti, u širinu: bijaše dvadeset i pet lakata; otvor pred otvorom."},{"v":14,"t":"Izmjeri i trijem: dvadeset lakata. Predvorje bijaše sve uokolo trijema vrata."},{"v":15,"t":"Od ulaznog pročelja vrata do nasuprotne strane njihova trijema bijaše pedeset lakata."},{"v":16,"t":"Na klijetima i njihovim dovracima, s unutrašnje strane sve uokolo, a tako i u trijemu, bijahu prozori s rešetkama. Takvi su prozori bili iznutra, sve naokolo, a na polustupovima palme."},{"v":17,"t":"Zatim me povede u vanjsko predvorje Doma. I gle, sve oko predvorja prostorije i pločnik. Trideset prostorija na pločniku."},{"v":18,"t":"Pločnik bijaše sa svake strane vrata i odgovaraše razini vrata. To je donji pločnik."},{"v":19,"t":"On izmjeri širinu predvorja od donjih vrata do unutrašnjega predvorja, s vanjske strane: sto lakata na istok i na sjever."},{"v":20,"t":"Sjevernim vratima vanjskoga predvorja izmjeri širinu i dužinu."},{"v":21,"t":"I ta su imala po tri klijeti sa svake strane, a stupovi im i trijemovi istih mjera kao u prvih vrata: pedeset lakata u dužinu i dvadeset i pet lakata u širinu."},{"v":22,"t":"Prozori im, trijemovi i palme bijahu iste mjere kao na istočnim vratima, a na prilazu im sedam stepenica; trijem im bijaše s unutrašnje strane."},{"v":23,"t":"Unutrašnje predvorje imaše vrata što bijahu nasuprot sjevernim vratima; kao i istočna. On izmjeri: između jednih i drugih vrata bijaše sto lakata."},{"v":24,"t":"Zatim me povede na jug, i gle: i ondje vrata. Izmjeri ondje klijeti, polustupove i trijemove: bijahu iste mjere."},{"v":25,"t":"Ona, kao i njihovi trijemovi, imahu sve uokolo prozore što bijahu kao i oni prvi. Dužina je i tu iznosila pedeset lakata, a širina dvadeset i pet."},{"v":26,"t":"K vratima je vodilo sedam stuba; trijem im je bio s unutrašnje strane, a na stupovima imahu po jednu palmu sa svake strane."},{"v":27,"t":"Unutrašnje predvorje imaše jedna vrata i s južne strane. On izmjeri: od tih vrata do južnih vrata - sto lakata."},{"v":28,"t":"Zatim me na južna vrata uvede u unutrašnje predvorje. I izmjeri južna vrata: bijahu istih mjera."},{"v":29,"t":"Klijeti, stupovi i trijemovi bijahu istih mjera. Vrata i njihov trijem imahu svud unaokolo prozore. Pedeset lakata bijaše tu u dužinu, dvadeset i pet lakata u širinu."},{"v":30,"t":"A sve uokolo trijemovi: dvadeset i pet lakata dugi, a pet lakata široki."},{"v":31,"t":"Trijemovi su se pružili prema vanjskom predvorju. Na polustupovima njihovim palme, a stubište im je imalo osam stuba."},{"v":32,"t":"Zatim me povede k istočnim vratima unutrašnjega predvorja. I izmjeri vrata: bijahu istih mjera."},{"v":33,"t":"Klijeti im, polustupovi i trijemovi bijahu također istih mjera. Vrata i njihov trijem imahu svud naokolo prozore. U dužinu bješe pedeset lakata, u širinu dvadeset i pet."},{"v":34,"t":"Trijem im se pružao prema vanjskom predvorju. Na njihovim polustupovima s ove i s one strane bijahu palme. Stubište im imaše osam stuba."},{"v":35,"t":"Zatim me povede k sjevernim vratima. I izmjeri ih: bijahu istih mjera."},{"v":36,"t":"Klijeti im, polustupovi i trijemovi bijahu također istih mjera. Vrata i njihov trijem imahu svud uokolo prozore. Pedeset je lakata tu bilo u dužinu, a dvadeset i pet u širinu."},{"v":37,"t":"Trijem je sezao do vanjskoga predvorja. Na polustupovima s ove i one strane bijahu palme. Stubište imaše osam stuba."},{"v":38,"t":"Uz trijemove vrata bijaše prostor s posebnim ulazom. Ondje su se ispirale žrtve paljenice."},{"v":39,"t":"U trijemu vrata s jedne i s druge strane bijahu po dva stola za klanje paljenicÄa, okajnicÄa i naknadnicÄa."},{"v":40,"t":"I s vanjske strane onomu tko ulazi na ulaz sjevernih vrata bijahu dva stola; i s druge strane, prema trijemu vrata, dva stola."},{"v":41,"t":"Četiri stola, dakle, s jedne, a četiri stola s druge strane vrata: u svemu osam stolova, na kojima se klahu žrtve."},{"v":42,"t":"Osim toga, četiri stola za paljenice, od klesanoga kamena. Bili su po lakat i pol široki i lakat visoki. Na njima je stajao pribor za klanje žrtava paljenica i klanica."},{"v":43,"t":"Stolovi bijahu sve uokolo obrubljeni žljebićima od jednoga dlana, zavrnutima unutra. Na stolove se stavljalo žrtveno meso."},{"v":44,"t":"Zatim me povede u unutrašnje predvorje. U unutrašnjem predvorju bijahu dvije prostorije: jedna bijaše sa strane sjevernih vrata, okrenuta prema jugu, a druga sa strane južnih vrata, okrenuta prema sjeveru."},{"v":45,"t":"I on mi reče: “Ta prostorija što je okrenuta na jug određena je za svećenike koji obavljaju službu u Domu."},{"v":46,"t":"A prostorija što je okrenuta na sjever jest za svećenike koji obavljaju službu na žrtveniku. To su sinovi Sadokovi, oni između sinova Levijevih koji smiju prići k Jahvi da mu služe!”"},{"v":47,"t":"On izmjeri predvorje. Dužina: sto lakata, širina: sto lakata; bijaše četverouglasto. Pred Domom stajaše žrtvenik."},{"v":48,"t":"A zatim me povede k trijemu. Izmjeri polustupove trijema: bijaše pet lakata na jednoj i pet lakata na drugoj strani. Vrata bijahu široka tri lakta s jedne i tri lakta s druge strane."},{"v":49,"t":"Trijem bijaše dugačak dvadeset lakata, a širok dvanaest lakata. Deset je stepenica vodilo onamo. Na dovratnicima s jedne i s druge strane stajaše po jedan stup."}]},"41":{"hr":[{"v":1,"t":"Zatim me povede u Hekal. Izmjeri mu polustupove: bijahu široki šest lakata s jedne i šest lakata s druge strane."},{"v":2,"t":"Vrata bijahu široka deset lakata: sa svake strane po jedno krilo od pet lakata. A zatim izmjeri Hekal: bijaše dugačak četrdeset, a širok dvadeset lakata."},{"v":3,"t":"Onda uđe i izmjeri polustupove vrata: dva lakta; zatim vrata: šest lakata; pa širinu vrata: sedam lakata."},{"v":4,"t":"Izmjeri zatim unutrašnji prostor: dužina dvadeset lakata, širina ispred Hekala dvadeset lakata. I reče mi: “To je Svetinja nad svetinjama.”"},{"v":5,"t":"Potom izmjeri zid Doma: šest lakata. Pobočne prostorije bijahu široke četiri lakta, sve oko Doma."},{"v":6,"t":"Pobočne prostorije bijahu jedna nad drugom, bijaše ih trideset na tri bÓoja. U hramskom zidu bijahu, sve uokolo, zasjeci da prihvate pobočne prostorije. Tako one ne bijahu ugrađene u hramski zid."},{"v":7,"t":"Širina se prostorija povećavala od boja do boja, jer su one sve uokolo, na bojeve, okruživale Dom, a Dom je, kako se uzlazilo, ostavljao sve širi prostor. S najdonjeg se boja uzlazilo na najgornji kroza srednji."},{"v":8,"t":"Onda vidjeh sve oko Doma neku uzvisinu. Osnove pobočnih prostorija: cijela trska, šest lakata."},{"v":9,"t":"Debljina vanjskoga zida pobočnih klijeti: pet lakata. Prolaz između pobočnih prostorija Doma"},{"v":10,"t":"i klijeti bijaše, sve uokolo Doma, dvadeset lakata širok."},{"v":11,"t":"Iz pobočne prostorije izlažahu na prolaz jedna vrata prema sjeveru i jedna prema jugu. Prolaz bijaše širok pet lakata svud uokolo."},{"v":12,"t":"Zdanje što zatvaraše ograđeni prostor sa zapada bijaše široko sedamdeset lakata, a zid te građevine posvud uokolo bijaše debeo pet lakata i dugačak devedeset lakata."},{"v":13,"t":"On izmjeri Dom: bijaše dugačak stotinu lakata. Ograđeni prostor, zdanje mu i zidovi, stotinu lakata dužine."},{"v":14,"t":"Širina pročelja Doma s ograđenim prostorom prema istoku: sto lakata."},{"v":15,"t":"On izmjeri dužinu zdanja duž ograđenog prostora što bijaše straga i hodnike s jedne i s druge strane: stotinu lakata. Unutrašnjost Hekala, trijemovi predvorja,"},{"v":16,"t":"pragovi, prozori s rešetkama i hodnici na sve tri strane uokolo, nasuprot pragovima, bijahu sve uokolo drvetom obloženi od zemlje do prozora. Prozori su bili zastrti."},{"v":17,"t":"Od ulaza sve do unutrašnjosti Doma, a tako i izvana te po svem zidu uokolo, iznutra i izvana,"},{"v":18,"t":"bijahu likovi kerubina i palma. Po jedna palma između dva kerubina, a svaki kerubin imaše dva lica:"},{"v":19,"t":"prema palmi s jedne strane lice čovječje, a prema palmi s druge strane lice lavlje. Tako bijaše po svemu Domu sve uokolo:"},{"v":20,"t":"od zemlje do ponad vrata bijahu izdjeljani kerubini i palme, a tako i po zidu Hekala."},{"v":21,"t":"Dovratnici Hekala bijahu četverouglasti."},{"v":22,"t":"Pred Svetištem nešto kao žrtvenik od drveta: tri lakta visok, dva lakta dugačak i dva lakta širok. Uglovi mu, podnožje i stranice bijahu od drveta. I čovjek mi reče: “Evo stola koji je pred licem Jahvinim!”"},{"v":23,"t":"I Hekal i Svetište imahu po dvoja vrata,"},{"v":24,"t":"a svaka vrata po dva krila što se obrtahu: dva krila u jednih i dva krila u drugih vrata."},{"v":25,"t":"A na vratima Hekala bijahu izdjeljani kerubini i palme, kao što bijahu izdjeljani i po zidovima. Izvana pred trijemom bijaše drvena nadstrešnica."},{"v":26,"t":"Prozori s rešetkama i palme bijahu s jedne i s druge strane na trijemu, u pobočnim prostorijama Doma i na nadstrešnici."}]},"42":{"hr":[{"v":1,"t":"A zatim me povede na sjever, u vanjsko predvorje, i dovede me do prostorija nasuprot ograđenom prostoru, nasuprot zdanju prema sjeveru."},{"v":2,"t":"Pročelje im sa sjeverne strane bijaše dugo sto lakata, a široko pedeset lakata."},{"v":3,"t":"Nasuprot vratima unutrašnjeg predvorja i nasuprot pločniku vanjskoga predvorja bijahu hodnici jedan prema drugome na tri boja."},{"v":4,"t":"Pred prostorijama bijaše prolaz prema unutrašnjosti - deset lakata širok i sto lakata dugačak. Vrata im bijahu okrenuta na sjever."},{"v":5,"t":"Gornje prostorije, jer im prostor oduzimahu hodnici, bijahu manje od donjih i srednjih."},{"v":6,"t":"Jer bijahu na tri boja, ali ne imahu stupova kao u predvorju. Zato gornje prostorije bijahu uže od donjih i srednjih."},{"v":7,"t":"Vanjski zid, duž klijeti, prema vanjskom predvorju, ispred klijeti, bijaše dugačak pedeset lakata."},{"v":8,"t":"Jer dužina klijetima vanjskoga predvorja bijaše pedeset lakata, a onima pred Hekalom sto lakata."},{"v":9,"t":"U tih prostorija bijaše ulaz s istoka onomu tko im prilazi iz vanjskog predvorja."},{"v":10,"t":"Po širini zida predvorja prema istoku, pred ograđenim prostorom i pred samim zdanjem, bijaše još prostorijÄa."},{"v":11,"t":"Pred njima bijaše prolaz kao ispred klijeti smještenih prema sjeveru: jednake dužine i jednake širine; i svi im izlazi, raspored i vrata bijahu jednaki."},{"v":12,"t":"Bili su kao ulazi u klijeti što bijahu prema jugu: ulaz na početku svakog prolaza, nasuprot zidu zdanja, prema istoku onomu tko bi u njih ulazio."},{"v":13,"t":"I reče mi: “Sjeverne i južne prostorije ispred ograđenog prostora jesu prostorije Svetišta: ondje svećenici koji prilaze Jahvi blaguju najveće svetinje. Oni će ovdje odlagati najveće svetinje, prinose, okajnice i naknadnice, jer je to mjesto sveto."},{"v":14,"t":"A kad svećenici budu ulazili, neće izlaziti iz Svetišta u vanjsko predvorje, nego će tu ostavljati odjeću u kojoj bijahu službu služili, jer je sveta, i oblačiti drugu odjeću da bi se mogli približiti mjestu određenu za narod.”"},{"v":15,"t":"Izmjerivši unutrašnjost Doma, izvede me na istočna vrata i izmjeri sve uokolo."},{"v":16,"t":"Mjeračkom trskom izmjeri istočnu stranu: bijaše pet stotina trska, mjeračkih trska,"},{"v":17,"t":"a zatim se okrenu i izmjeri sjevernu stranu: bijaše pet stotina trska, mjeračkih trska."},{"v":18,"t":"Tada se okrenu na južnu stranu i izmjeri: pet stotina trska, mjeračkih trska."},{"v":19,"t":"Potom se okrenu na zapadnu stranu i izmjeri: pet stotina trska, mjeračkih trska."},{"v":20,"t":"On izmjeri zid na sve četiri strane uokolo: bijaše pet stotina trska dugačak i pet stotina širok. Odvajao je sveto mjesto od nesvetoga."}]},"43":{"hr":[{"v":1,"t":"Zatim me povede k vratima što gledaju na istok."},{"v":2,"t":"I gle, Slava Boga Izraelova dolazi od istoka; šum joj kao šum velikih voda: i zemlja se sjala od slave njegove."},{"v":3,"t":"To viđenje koje gledah bijaše kao viđenje što ga vidjeh kad dođoh da uništim grad i kao viđenje koje vidjeh na rijeci Kebaru. Padoh ničice."},{"v":4,"t":"A Slava Jahvina uđe u Dom na vrata koja gledaju na istok."},{"v":5,"t":"Tada me duh podiže i odvede u unutrašnje predvorje. I gle: Dom bijaše pun Slave Jahvine."},{"v":6,"t":"I čuh glas koji mi iz Doma govori, a kraj mene netko stajaše."},{"v":7,"t":"I reče mi: “Sine čovječji, ovo je mjesto mojega prijestolja, ovo je mjesto stopa mojih nogu: ovdje ću, posred sinova Izraelovih, prebivati zauvijek. Izraelov dom neće više oskvrnjivati moje sveto ime - ni oni ni njihovi kraljevi - svojim bludništvom i truplima svojih kraljeva:"},{"v":8,"t":"stavili su svoj prag do moga, svoje dovratnike do mojih, tako da je bio samo zid između mene i njih, i oskvrnjivali su moje sveto ime gnusobama koje počiniše. I zato ih zatrijeh u svojem gnjevu."},{"v":9,"t":"Sada će oni ukloniti daleko od mene svoje bludništvo i trupla svojih kraljeva, a ja ću zauvijek prebivati posred njih."},{"v":10,"t":"Sine čovječji, pokaži domu Izraelovu ovaj Dom da se posrame sa svojih bezakonja. Neka mu izmjere razmjere."},{"v":11,"t":"Ako se posrame zbog svega što učiniše, opiši im Dom i njegove razmjere, njegove izlaze i ulaze, sve njegovo obličje, sve propise i sve zakone; upoznaj ih i nacrtaj im da vide i da čuvaju i provedu sve njegovo obličje i sve propise o njemu."},{"v":12,"t":"A ovo je zakon za Dom: navrh gore, sav prostor uokolo, bit će najsvetija svetinja."},{"v":13,"t":"Ovo su mjere žrtvenika, na laktove - a lakat je ovdje jedan lakat i pedalj: podnožje žrtvenika lakat dugo, lakat široko; obrub kojim je obrubljen uokolo - jedan pedalj. Visina žrtvenika:"},{"v":14,"t":"od podnožja na zemlji do donjega pojasa žrtvenika - dva lakta, a u širinu jedan lakat; od manjeg pojasa do većega četiri lakta, a u širinu jedan lakat."},{"v":15,"t":"A samo žrtvište: četiri lakta visoko. A sa žrtvišta dižu se uvis četiri roga."},{"v":16,"t":"Žrtvište: dvanaest lakata dugo, dvanaest lakata široko, četvorina, na sve četiri strane."},{"v":17,"t":"A pojas: četrnaest lakata dug i četrnaest lakata širok, na četiri strane; njegov rub uokolo pol lakta, a podnožje oko njega uokolo jedan lakat; stepenice mu gledaju na istok.”"},{"v":18,"t":"I reče mi: “Sine čovječji, ovako govori Jahve Gospod: 'Ovo su propisi žrtveni po kojima se u svoje vrijeme mora podići žrtvenik da se na njemu prinose paljenice i da se po njemu škropi krvlju."},{"v":19,"t":"Svećenicima levitima, potomcima Sadokovim, koji pristupaju k meni da mi služe - riječ je Jahve Gospoda - dat ćeš june za žrtvu okajnicu."},{"v":20,"t":"Uzet ćeš njegove krvi i njome pomazati četiri roga žrtvišta i četiri ugla pojasa i obrub sve uokolo da okajnicom pomiriš žrtvenik."},{"v":21,"t":"Zatim uzmi june i spali ga na odijeljenom mjestu Doma, izvan Svetišta."},{"v":22,"t":"Sutradan prinesi jarca bez mane kao okajnicu, neka se njime okaje žrtvenik kao što je okajan junetom."},{"v":23,"t":"A kad ga okaješ, prinesi junca bez mane i ovna bez mane iz stada:"},{"v":24,"t":"prikaži ih pred Jahvom, a svećenici neka ih pospu solju i neka ih prinesu kao paljenicu Jahvi."},{"v":25,"t":"Sedam dana svaki dan prinesi jednog jarca za grijeh; i neka se prinese june i ovan iz stada, oba bez mane."},{"v":26,"t":"Sedam dana neka se pomiruje žrtvenik i neka se čisti i posvećuje."},{"v":27,"t":"Pošto se navrše ti dani, od osmoga dana unapredak neka svećenici žrtvuju na žrtveniku vaše paljenice i pričesnice; i omiljet ćete mi' - riječ je Jahve Gospoda.”"}]},"44":{"hr":[{"v":1,"t":"Potom me odvede natrag k izvanjskim vratima Svetišta, koja gledaju na istok: bijahu zatvorena."},{"v":2,"t":"I reče mi Jahve: “Ova će vrata biti zatvorena; neka se ne otvaraju i nitko neka ne ulazi na njih, jer ja, Jahve, Bog Izraelov, kroz njih prođoh - zato neka budu zatvorena."},{"v":3,"t":"Samo knez, jer je knez, smije sjesti tu i blagovati pred Jahvom; tada neka uđe kroz trijem vrata i istim putem neka izađe.”"},{"v":4,"t":"Zatim me odvede k sjevernim vratima pred Dom. Pogledah, i gle: Slava Jahvina bijaše napunila Dom Jahvin. Padoh ničice."},{"v":5,"t":"Jahve mi reče: “Sine čovječji, pomno pripazi, dobro gledaj i pažljivo poslušaj što ću ti reći o svim uredbama Doma Jahvina i o svim njegovim zakonima. Dobro pazi tko smije ući u Dom i tko je iz Svetišta odijeljen."},{"v":6,"t":"Reci rodu odmetničkom, domu Izraelovu: 'Ovako govori Jahve Gospod: Previše je već vaših gnusoba, dome Izraelov!"},{"v":7,"t":"Uvodili ste tuđince, neobrezana srca i neobrezana tijela, te su ušli u moje Svetište i oskvrnuli moj Dom dok ste vi prinosili moj kruh i pretilinu i krv; i tako ste raskinuli moj Savez svim tim gnusobama."},{"v":8,"t":"Niste sami čuvali moje svetinje, nego ste njih namjestili namjesto sebe kao čuvare u mojem Svetištu.'"},{"v":9,"t":"Ovako govori Jahve Gospod: 'Nijedan tuđinac, neobrezana srca i neobrezana tijela, da više ne ulazi u moje Svetište - nijedan tuđinac koji živi među sinovima Izraelovim."},{"v":10,"t":"A leviti koji su se udaljili od mene, kad je ono Izrael odlutao od mene za svojim kumirima, snosit će svoje bezakonje."},{"v":11,"t":"Služit će u Svetištu samo kao stražari na vratima Doma i kao posluga Domu: klat će narodu paljenice i druge žrtve i bit će mu na službu."},{"v":12,"t":"Služili su im pred njihovim kumirima i tako naveli Dom Izraelov na bezakonje. Zato podigoh ruku na njih - riječ je Jahve Gospoda - da snose svoje bezakonje."},{"v":13,"t":"Više neće pristupati k meni da mi služe kao svećenici i neće više prilaziti mojim najsvetijim svetinjama, nego će snositi svoju sramotu i gnusobe koje počiniše."},{"v":14,"t":"Postavit ću ih da u Domu rade svaki posao i sve što treba u njemu svršiti."},{"v":15,"t":"Svećenici leviti, potomci Sadokovi, koji su mi vjerno služili u mojem Svetištu kad su ono sinovi Izraelovi odlutali od mene - oni smiju pristupati k meni da mi služe: služit će preda mnom prinoseći mi pretilinu i krv - riječ je Jahve Gospoda."},{"v":16,"t":"Oni smiju ulaziti u moje Svetište i pristupati k mojem stolu da mi služe i da vrše službu."},{"v":17,"t":"Kad budu ulazili na vrata unutrašnjega predvorja, neka obuku lanene haljine: neka ne bude na njima ništa vuneno kad služe na vratima unutrašnjega predvorja i Doma."},{"v":18,"t":"Na glavama neka nose lanene kape, oko bokova gaće lanene: neka se ne pašu ničim od čega bi se znojili."},{"v":19,"t":"Kad izlaze u vanjsko predvorje k narodu, neka svuku haljine u kojima su služili i neka ih ostave u prostorijama Svetišta, a neka obuku druge haljine, da ne posvete puk svojim haljinama."},{"v":20,"t":"I neka ne briju glave, a ni bujne kose neka ne puštaju, nego neka strigu kosu."},{"v":21,"t":"I nijedan svećenik, kad mu je poći u unutrašnje predvorje, neka ne pije vina."},{"v":22,"t":"Neka se ne žene udovicom ili puštenicom nego samo djevojkom iz roda Izraelova ili udovicom svećenikovom."},{"v":23,"t":"Neka mi narod uče razlikovati sveto od nesvetoga, lučiti nečisto od čistoga."},{"v":24,"t":"U parnicama oni neka budu suci: neka sude po mojim zakonima; i neka čuvaju zakone i uredbe o svim mojim blagdanima i neka svetkuju moje subote."},{"v":25,"t":"K mrtvacu neka ne prilaze da se ne okaljaju; samo za ocem i za majkom, za sinom i kćerju, za bratom i sestrom još neudatom smiju se okaljati."},{"v":26,"t":"Pošto se nakon toga koji očisti, neka mu se broji sedam dana:"},{"v":27,"t":"a onda kad uđe u Svetište, u unutrašnje predvorje da služi u Svetištu, neka prinese žrtvu okajnicu - riječ je Jahve Gospoda."},{"v":28,"t":"Njima ne pripada nikakva baština - ja sam njihova baština; i zato im ne dajte nikakva posjeda u Izraelu - ja sam posjed njihov."},{"v":29,"t":"Hranit će se od žrtava prinosnica, okajnica i naknadnica, i sve zavjetovano u Izraelu njima pripada."},{"v":30,"t":"Najbolje od svih vaših prvina i od svih vaših prinosa koje ćete prinositi pripada svećenicima; njima ćete davati i najbolje brašno, da blagoslov počiva na vašim domovima."},{"v":31,"t":"Svećenici ne smiju jesti mesa od uginulih i razderanih životinja - bilo od ptica ili stoke."}]},"45":{"hr":[{"v":1,"t":"Kad budete zemlju ždrijebom dijelili u baštinu, prinesite kao prinos pridržan Jahvi jedan sveti dio zemlje, dugačak dvadeset i pet tisuća lakata, širok deset tisuća; to neka bude sveto područje uzduž i poprijeko."},{"v":2,"t":"Od toga neka bude za Svetište četvorina od pet stotina lakata i čistina od deset lakata uokolo."},{"v":3,"t":"Od toga područja izmjeri u dužinu dvadeset i pet tisuća lakata, a u širinu deset tisuća: tu neka bude Svetište - Svetinja nad svetinjama."},{"v":4,"t":"Taj sveti dio zemlje pripada svećenicima koji služe u Svetištu i koji pristupaju k Jahvi da mu služe: tu neka im bude mjesto za kuće; i to neka je sveto mjesto koje pripada Svetištu."},{"v":5,"t":"Dvadeset i pet tisuća u dužinu i deset tisuća u širinu neka bude levitima koji služe Domu: neka ondje sagrade gradove u kojima će stanovati."},{"v":6,"t":"Za posjed gradu dodijelite pet tisuća lakata u širinu i dvadeset i pet tisuća lakata u dužinu usporedo sa svetim područjem: to će pripadati svemu domu Izraelovu."},{"v":7,"t":"Knezu pripada dio s obje strane svetoga područja i gradskoga posjeda - duž svetoga područja i duž gradskoga posjeda - od zapadne strane prema zapadu i od istočne strane prema istoku, a dužina neka bude jednaka svakom tom dijelu, od zapadne do istočne granice."},{"v":8,"t":"To neka bude njegova zemlja, posjed u Izraelu, da knezovi više ne tlače narod moj i da zemlju dadu domu Izraelovu po plemenima.'"},{"v":9,"t":"Ovako govori Jahve Gospod: 'Dosta je, knezovi Izraelovi! Okanite se nasilja i pljačke i vršite zakon i pravdu; izbavite narod moj od svojih tražbina - riječ je Jahve Gospoda."},{"v":10,"t":"Mjerite pravom mjerom: pravom efom i pravim batom."},{"v":11,"t":"Efa i bat neka jednako hvataju: bat neka iznosi desetinu homera i efa desetinu homera - neka im mjera bude prema homeru."},{"v":12,"t":"Šekel neka bude dvadeset gera; mina neka vam bude dvadeset šekela, dvadeset i pet šekela i petnaest šekela."},{"v":13,"t":"Ovo je prinos koji ćete prinositi: šestinu efe od svakoga homera pšenice i šestinu efe od svakoga homera ječma."},{"v":14,"t":"A za ulje ova je uredba: desetina bata od svakoga kora - deset bata jedan je kor."},{"v":15,"t":"Od svakoga stada od dvije stotine ovaca sa sočnih izraelskih pašnjaka po jednu ovcu za žrtvu prinosnicu, paljenicu i pričesnicu - vama za pomirenje - riječ je Jahve Gospoda."},{"v":16,"t":"Sav narod zemlje duguje ovaj prinos knezu Izraelovu."},{"v":17,"t":"A knez je dužan davati žrtve paljenice, prinosnice i ljevanice za svetkovine i za mlađake, za subote i blagdane doma Izraelova: on neka se postara za okajnicu, za pomirnicu, prinosnicu, paljenicu i pričesnicu za pomirenje doma Izraelova.'"},{"v":18,"t":"Ovako govori Jahve Gospod: 'Prvoga mjeseca, prvoga dana u mjesecu, uzmi june bez mane i okaj njime Svetište."},{"v":19,"t":"Svećenik neka uzme krvi te žrtve okajnice i neka njome pomaže dovratnike Doma i sva četiri ugla pojasa žrtveničkoga i dovratnike vrata unutrašnjega predvorja."},{"v":20,"t":"Tako neka učini i sedmoga dana istoga mjeseca za svakoga koji je sagriješio iz slabosti i neznanja. Tako ćete dovršiti pomirenje Doma."},{"v":21,"t":"Prvoga mjeseca, četrnaestoga dana u mjesecu, svetkujte Pashu, sedmodnevni blagdan, kad se blaguju beskvasni hljebovi."},{"v":22,"t":"Toga dana neka knez za se i za sav puk zemlje prinese june za okajnicu."},{"v":23,"t":"Sedam dana blagdana neka prinosi za paljenicu Jahvi sedam junčića i sedam ovnova bez mane - svaki dan tih sedam dana - i svaki dan jarca kao okajnicu."},{"v":24,"t":"A kao prinosnicu neka prinese efu po svakom juncu i efu po ovnu i hin ulja na svaku efu."},{"v":25,"t":"Sedmoga mjeseca, petnaestoga dana u mjesecu, neka o blagdanu isto toliko prinosi sedam dana: isto toliko okajnica, paljenica, prinosnica i ulja.'"}]},"46":{"hr":[{"v":1,"t":"Ovako govori Jahve Gospod: 'Vrata unutrašnjega predvorja, koja gledaju na istok, neka budu zatvorena šest radnih dana, a neka se otvaraju u dan subotnji; i u dan mlađaka neka se otvaraju."},{"v":2,"t":"Knez neka ulazi kroz njihov trijem i neka stane kod dovratnika; svećenici će tada prinijeti njegovu paljenicu i pričesnicu, a on će se pokloniti na pragu vrata i izaći. Neka se vrata ne zatvaraju do večeri."},{"v":3,"t":"Na ulazu istih vrata subotom i na mlađake klanjat će se Jahvi puk zemlje."},{"v":4,"t":"Paljenica koju će knez subotom prinositi Jahvi neka bude: šest jaganjaca bez mane, ovan bez mane."},{"v":5,"t":"A prinosnica neka bude efa po ovnu, a po jaganjcu koliko i kako tko može i hin ulja po efi."},{"v":6,"t":"Na dan mlađaka neka se prinese june bez mane, šest jaganjaca i ovan bez mane."},{"v":7,"t":"A za prinosnicu neka se prinese efa po junetu, efa po ovnu, a po jaganjcu koliko tko može i hin ulja po efi."},{"v":8,"t":"Kad knez bude ulazio, neka ulazi kroz trijem vrata i istim putem neka izlazi."},{"v":9,"t":"A kad puk zemlje o blagdanima dolazi pred Jahvu, onaj koji na sjeverna vrata uđe da se pokloni neka izađe na južna, a tko uđe na južna neka izađe na sjeverna: neka se ne vraća na vrata na koja je ušao, nego neka izađe na suprotna."},{"v":10,"t":"I knez neka bude s njima: kad oni ulaze, neka i on uđe i neka izađe kad oni izlaze."},{"v":11,"t":"O blagdanima i svetkovinama neka se kao prinosnica prinese efa po juncu i efa po ovnu, a po jaganjcu koliko tko može i hin ulja po efi."},{"v":12,"t":"Kad knez želi prinijeti dobrovoljnu paljenicu ili dobrovoljnu pričesnicu Jahvi, neka mu se otvore vrata koja gledaju na istok, pa neka prinese paljenicu i svoju pričesnicu kao na dan subotnji; potom neka iziđe, a kad iziđe, neka se zatvore vrata."},{"v":13,"t":"Svaki dan prinijet ćeš Jahvi za paljenicu janje od godine, bez mane; prinijet ćeš ga svako jutro."},{"v":14,"t":"A kao prinosnicu na nj prinesi svako jutro šestinu efe i trećinu hina ulja da se poškropi najfinije brašno; to neka bude svagdašnji prinos Jahvi po vječnoj uredbi."},{"v":15,"t":"Treba dakle prinijeti jagnje, prinosnicu i ulje svako jutro kao svagdašnju žrtvu paljenicu.'"},{"v":16,"t":"Ovako govori Jahve Gospod: 'Dadne li knez dar komu svom sinu od svoje baštine, taj će dar pripasti njima u posjed kao baština."},{"v":17,"t":"Ako li od svoje baštine dade dar komu svom sluzi, tome će to pripadati do otpusne godine, a potom neka se vrati knezu; baština pripada samo kneževim sinovima."},{"v":18,"t":"Knez ne smije prisvojiti ništa od baštine naroda, pljačkajući narodni posjed. Sinovima svojim neka dade baštinu od svojega posjeda, da se ne raspe narod potjeran sa svojega posjeda.'”"},{"v":19,"t":"Zatim me odvede kroz ulaz kraj vrata, u svećeničke prostorije Svetišta što gledaju na sjever. I gle: ondje, u dnu, prema zapadu, jedan prostor!"},{"v":20,"t":"I reče mi: “Ovo je mjesto gdje će svećenici kuhati žrtve naknadnice i okajnice i žrtvu pomirnicu, gdje će peći prinosnice da ih ne iznose u vanjsko predvorje te ne posvete naroda.”"},{"v":21,"t":"Potom me izvede u vanjsko predvorje i provede kraj četiri ugla predvorja, i gle, u svakom uglu predvorja bijaše malo predvorje."},{"v":22,"t":"Ta mala predvorja u četiri ugla predvorja bijahu četrdeset lakata dugačka, trideset široka - sva četiri istih razmjera;"},{"v":23,"t":"sva četiri zidom opasana, a pod zidom sve uokolo bijahu sagrađena ognjišta."},{"v":24,"t":"I reče mi: “To su kuhinje gdje će sluge Doma kuhati puku žrtve.”"}]},"47":{"hr":[{"v":1,"t":"Zatim me odvede natrag k vratima Doma. I gle: voda izvirala ispod praga Doma, prema istoku - jer pročelje Doma bijaše prema istoku - i voda otjecaše ispod desne strane Doma, južno od žrtvenika."},{"v":2,"t":"Zatim me izvede na sjeverna vrata i provede me uokolo vanjskim putem k vanjskim vratima koja gledaju na istok. I gle, voda izvirala s desne strane."},{"v":3,"t":"Čovjek pođe prema istoku s užetom u ruci, izmjeri tisuću lakata i prevede me preko vode, a voda mi sezaše do gležanja."},{"v":4,"t":"Ondje opet izmjeri tisuću lakata i provede me preko vode, a voda bijaše do koljena. I opet izmjeri tisuću lakata i prevede me preko vode što bijaše do bokova."},{"v":5,"t":"Opet izmjeri tisuću lakata, ali ondje bijaše potok koji ne mogoh prijeći jer je voda nabujala te je trebalo plivati: bijaše to potok koji se ne može prijeći."},{"v":6,"t":"I upita me: “Vidiš li, sine čovječji?” I odvede me natrag, na obalu potoka."},{"v":7,"t":"I kad se vratih, gle, na obali s obje strane mnoga stabla."},{"v":8,"t":"I reče mi: “Ova voda teče u istočni kraj, spušta se u Arabu i teče u more; a kad se u more izlije, vode mu ozdrave."},{"v":9,"t":"I kuda god potok protječe, sve živo što se miče oživi; i bit će vrlo mnogo riba, jer kamo god dođe ova voda, sve ozdravi i oživi - kuda god protječe ovaj potok."},{"v":10,"t":"I ribari će ribariti duž mora: od En Gedija do En Eglajima sušit će se mreže; i bit će vrlo mnogo svakovrsnih riba kao u Velikom moru."},{"v":11,"t":"A močvare onoga mora i njegove bare neće ozdraviti: bit će za sol."},{"v":12,"t":"Duž potoka na obje strane rast će svakovrsne voćke: lišće im neće otpadati i s njih neće nestajati ploda; svakog će mjeseca roditi novim plodom jer im voda dotječe iz Svetišta. Plod će njihov biti za jelo, a lišće za lijek'."},{"v":13,"t":"Ovako govori Jahve Gospod: 'Ovo su granice u kojima ćete podijeliti zemlju u baštinu među dvanaest plemena Izraelovih - Josipu dva dijela."},{"v":14,"t":"Svakom će od vas pripasti podjednako od zemlje koju se zakleh dati vašim ocima, a vama će pripasti u baštinu."},{"v":15,"t":"Ovo su, dakle, granice zemlje: na sjeveru, od Velikoga mora put Hetlona do Ulaza u Hamat: Sedad,"},{"v":16,"t":"Berota, Sibrajim, između kraja damaščanskog i hamatskoga, i Haser Enon, prema granici hauranskoj."},{"v":17,"t":"Granica će se, dakle, protezati od mora do Haser Enona, kojemu je na sjeveru kraj damaščanski i hamatski - sjeverna strana."},{"v":18,"t":"Istočna strana: između Haurana i Damaska, između Gileada i zemlje izraelske, pa Jordanom kao granicom prema istočnomu moru do Tamara - istočna strana."},{"v":19,"t":"Južna strana: prema jugu od Tamara do Meripskih voda i Kadeša pa potokom prema Velikomu moru - južna strana, prema jugu."},{"v":20,"t":"A zapadna strana: granica je Veliko more pa do nadomak Ulaza u Hamat - zapadna strana."},{"v":21,"t":"Tu zemlju razdijelite među sobom po plemenima Izraelovim."},{"v":22,"t":"Razdijelit ćete je ždrijebom u baštinu između sebe i između došljaka koji žive među vama i koji među vama djecu narodiše: i njih ćete smatrati domorocima među Izraelovim sinovima, da i oni dobiju ždrijebom baštinu među Izraelovim sinovima."},{"v":23,"t":"Svakome tom došljaku dodijelite baštinu u plemenu u kojem živi - riječ je Jahve Gospoda."}]},"48":{"hr":[{"v":1,"t":"A ovo su imena plemenÄa: od krajnjega sjevera put Hetlona prema Ulazu u Hamat i Haser Enon, od damaščanskoga kraja na sjeveru duž Hamata, od istoka do zapada - dio Danov."},{"v":2,"t":"Uz područje Danovo, od istoka do zapada - dio Ašerov."},{"v":3,"t":"Uz područje Ašerovo, od istoka do zapada - dio Naftalijev."},{"v":4,"t":"Uz područje Naftalijevo, od istoka do zapada - dio Manašeov."},{"v":5,"t":"Uz područje Manašeovo, od istoka do zapada - dio Efrajimov."},{"v":6,"t":"Uz područje Efrajimovo, od istoka do zapada - dio Rubenov."},{"v":7,"t":"Uz područje Rubenovo, od istoka do zapada - dio Judin."},{"v":8,"t":"Uz područje Judino, od istoka do zapada neka bude pridržano područje koje ćete Jahvi prinijeti: dvadeset i pet tisuća lakata u širinu, a u dužinu kao svaki drugi dio, od istoka do zapada. U sredini neka bude Svetište."},{"v":9,"t":"To pridržano područje koje ćete Jahvi prinijeti neka bude dugačko dvadeset i pet tisuća lakata, široko deset tisuća."},{"v":10,"t":"To sveto, prineseno područje za svećenike neka bude na sjeveru dvadeset i pet tisuća lakata; prema zapadu široko deset tisuća, prema istoku široko deset tisuća; prema jugu dugačko dvadeset i pet tisuća. U sredini neka bude Jahvino Svetište."},{"v":11,"t":"A posvećenim svećenicima, potomcima Sadokovim, koji su mi vjerno služili i nisu, kao leviti, zastranili kad su ono zastranili sinovi Izraelovi:"},{"v":12,"t":"njima će pripasti dio od toga najsvetijeg područja zemlje, uz područje levitsko."},{"v":13,"t":"A levitima, baš kao i području svećeničkom: dvadeset i pet tisuća lakata u dužinu i deset tisuća lakata u širinu - ukupno dvadeset i pet tisuća lakata u dužinu, deset tisuća u širinu."},{"v":14,"t":"Od toga se ništa ne smije prodati ni zamijeniti; ne smije se ni na koga prenijeti ta prvina zemlje, jer je Jahvi posvećena."},{"v":15,"t":"Pet tisuća lakata u širinu, što ostane od onih dvadeset i pet tisuća, neka bude opće područje: za grad, za naselje i za čistinu. Grad neka bude u sredini."},{"v":16,"t":"Evo mjerÄa: sa sjevera četiri tisuće i pet stotina lakata; s juga četiri tisuće i pet stotina; s istoka četiri tisuće i pet stotina; sa zapada četiri tisuće i pet stotina."},{"v":17,"t":"A čistina oko grada: dvije stotine i pedeset lakata prema sjeveru, dvije stotine i pedeset prema jugu, dvije stotine i pedeset prema istoku, dvije stotine i pedeset prema zapadu."},{"v":18,"t":"Što ostane u dužinu, duž svetoga područja - deset tisuća lakata prema istoku i deset tisuća prema zapadu, duž svetoga područja - to neka bude za uzdržavanje onih koji služe gradu."},{"v":19,"t":"Ti koji služe gradu uzimat će se iz svih plemena Izraelovih."},{"v":20,"t":"Sve, dakle, pridržano područje - dvadeset i pet tisuća lakata sa dvadeset i pet tisuća, u četverokut - prinijet ćete Jahvi: i sveto područje i posjed gradski."},{"v":21,"t":"Knezu pripada što preostane: s obje strane svetoga područja i posjeda gradskoga - prema istoku dvadeset i pet tisuća lakata, prema istočnoj strani, i prema zapadu dvadeset i pet tisuća lakata, prema zapadnoj strani, usporedo s drugim područjima - sve je to kneževo. A u sredini je sveto područje i Svetište Doma."},{"v":22,"t":"Od levitskoga posjeda i od posjeda gradskoga - koje je usred kneževa - i između Judina i Benjaminova područja: kneževo je."},{"v":23,"t":"Ostala plemena: od istoka do zapada - dio Benjaminov."},{"v":24,"t":"Uz područje Benjaminovo, od istoka do zapada - dio Šimunov."},{"v":25,"t":"uz područje Šimunovo, od istoka do zapada - dio Jisakarov."},{"v":26,"t":"Uz područje Jisakarovo, od istoka do zapada - dio Zebulunov."},{"v":27,"t":"Uz područje Zebulunovo, od istoka do zapada - dio Gadov."},{"v":28,"t":"Uz područje Gadovo, na južnoj strani, prema jugu, ide granica od Tamara do Meripskih voda i Kadeša, pa potokom prema Velikome moru."},{"v":29,"t":"To je zemlja koju ćete ždrijebom razdijeliti u baštinu plemenima Izraelovim, to su njihovi dijelovi - riječ je Jahve Gospoda."},{"v":30,"t":"[30a] A ovo su gradska vrata"},{"v":31,"t":"[31a] koja će se zvati po Izraelovim plemenima. [30b] Na sjevernoj strani - četiri tisuće i pet stotina lakata u dužinu - [31b] troja vrata: Vrata Rubenova, Vrata Judina, Vrata Levijeva."},{"v":32,"t":"Na istočnoj strani - četiri tisuće i pet stotina lakata u dužinu - troja vrata: Vrata Josipova, Vrata Benjaminova, Vrata Danova."},{"v":33,"t":"Na južnoj strani - četiri tisuće i pet stotina lakata u dužinu - troja vrata: Vrata Šimunova, Vrata Jisakarova, Vrata Zebulunova."},{"v":34,"t":"Sa zapadne strane - četiri tisuće i pet stotina lakata u dužinu - troja vrata: Vrata Gadova, Vrata Ašerova, Vrata Naftalijeva."},{"v":35,"t":"Sve uokolo: osamnaest tisuća lakata. A ime će gradu unapredak biti: 'Jahve je ovdje.'”"}]}},"DAN":{"1":{"hr":[{"v":1,"t":"Treće godine kraljevanja Jojakima, kralja Judeje, dođe Nabukodonozor, kralj Babilona, na Jeruzalem te ga opsjede."},{"v":2,"t":"Gospodin mu dade u ruke Jojakima, kralja judejskog, i dio predmeta iz Doma Božjega; on ih dopremi u zemlju Šinear i pohrani predmete u riznici svojih bogova."},{"v":3,"t":"Kralj naredi Ašfenazu, starješini svojih dvorjanika, da dovede od Izraelaca nekoliko dječaka kraljevskoga ili velikaškog roda:"},{"v":4,"t":"neka budu bez nedostatka, lijepi, vrsni u svakoj mudrosti, dobro poučeni i bistri, prikladni da stoje na kraljevu dvoru; Ašfenaz neka ih nauči pismu i jeziku Kaldejaca."},{"v":5,"t":"Kralj im odredi dnevni obrok od kraljevskih jela i od vina sa svoga stola. Neka se odgajaju tri godine, a poslije toga imali bi stajati pred kraljem."},{"v":6,"t":"Među njima bijahu Judejci: Daniel, Hananija, Mišael i Azarja."},{"v":7,"t":"Dvorjanički starješina nadjene im imena: Daniel će se zvati Baltazar, Hananija Šadrak, Mišael Mešak, Azarja Abed Nego."},{"v":8,"t":"Daniel je u srcu odlučio da se neće okaljati kraljevim jelima i vinom s njegova stola, pa zamoli dvorjaničkog starješinu da ga poštedi te se ne okalja."},{"v":9,"t":"Bog dade Danielu te nađe dobrohotnost i smilovanje u dvorjaničkog starješine."},{"v":10,"t":"Starješina reče Danielu: “Bojim se svoga gospodara kralja; on vam je odredio jelo i pilo, pa ako vidi da su vam lica mršavija nego u drugih dječaka vaše dobi, ja ću zbog vas biti kriv pred kraljem.”"},{"v":11,"t":"Tada reče Daniel čuvaru koga bijaše dvorjanički starješina odredio Danielu, Hananiji, Mišaelu i Azarji:"},{"v":12,"t":"“Molim te, pokušaj sa svojim slugama deset dana: neka nam se daje povrće za jelo i voda za pilo."},{"v":13,"t":"Vidjet ćeš onda kakvi ćemo biti mi a kakvi dječaci koji jedu od kraljevih jela, pa učini sa svojim slugama po onome što budeš vidio.”"},{"v":14,"t":"On pristade i stavi ih na kušnju deset dana."},{"v":15,"t":"A nakon deset dana oni bijahu ljepši i ugojeniji nego svi dječaci koji jeđahu od kraljevih jela."},{"v":16,"t":"Od tada čuvar dokinu njihova jela i obrok vina što su imali piti te im davaše povrća."},{"v":17,"t":"Ovoj četvorici dječaka dade Bog znanje i razumijevanje svih knjiga i mudrosti. Daniel razumijevaše viđenja i sne."},{"v":18,"t":"Pošto se navršilo vrijeme određeno od kralja da mu ih dovedu, dvorjanički starješina uvede ih pred Nabukodonozora."},{"v":19,"t":"Kralj razgovaraše s njima i među svima ne nađe se nijedan kao Daniel, Hananija, Mišael i Azarja. I tako oni ostadoše pred kraljem."},{"v":20,"t":"I u svemu mudrom i umnom o čemu ih ispitivaše kralj nađe da su deset puta vrsniji od svih čarobnika i gatalaca što ih bijaše u svem njegovu kraljevstvu."},{"v":21,"t":"Daniel ostade ondje do prve godine kralja Kira."}]},"2":{"hr":[{"v":1,"t":"Druge godine Nabukodonozorova kraljevanja usni Nabukodonozor sanje: njegov se duh zbog toga uznemiri, a san ga ostavi."},{"v":2,"t":"Kralj naredi da se pozovu čarobnici i gataoci, zaklinjači i zvjezdari da protumače kralju njegove sanje."},{"v":3,"t":"Dođoše dakle te stadoše pred kralja. Kralj im reče: “Usnih jednu sanju i moj se duh uznemiri od želje da razumijem sanju.”"},{"v":4,"t":"Kaldejci odgovoriše kralju (aramejski): “O kralju, živ bio dovijeka! Pripovjedi svoju sanju slugama svojim, a mi ćemo ti otkriti njezino značenje.”"},{"v":5,"t":"Kralj odgovori i reče zvjezdarima: “Moja je odluka neopoziva: ako mi ne kažete što sam snio i što san znači, bit ćete rastrgani u komade, a vaše će kuće postati smetišta."},{"v":6,"t":"No ako mi otkrijete moju sanju i njezino značenje, dobit ćete od mene darove i poklone i velike časti. Otkrijte mi dakle što sam snio i što san znači.”"},{"v":7,"t":"Oni opet odgovoriše: “Neka kralj rekne svoju sanju slugama svojim, a mi ćemo mu otkriti njezino značenje.”"},{"v":8,"t":"A kralj: “Dobro ja znam da želite dobiti na vremenu jer znate da je moja odluka neopoziva."},{"v":9,"t":"Ako mi ne kažete što sam snio, znači da me namjeravate obmanjivati varavim riječima i izmišljotinama dok nekako ne prođe vrijeme. Stoga, recite mi moj san, pa ću znati da li mi možete kazati i njegovo značenje!”"},{"v":10,"t":"Zvjezdari odgovoriše pred kraljem: “Nema na svijetu čovjeka koji bi takvo što mogao otkriti kralju. I stoga nijedan kralj, ma kako velik i moćan, takvo što ne traži od čarobnika, gataoca ili zvjezdara."},{"v":11,"t":"Što tražiš, kralju, teško je, i nema ga tko bi to mogao otkriti kralju osim bogova, koji ne borave među smrtnicima.”"},{"v":12,"t":"Tada se kralj silno razgnjevi i razbjesni te naredi da se pogube svi mudraci babilonski."},{"v":13,"t":"Pošto je objavljena naredba da se ubiju mudraci, potražiše i Daniela i njegove drugove da ih pogube."},{"v":14,"t":"No Daniel se mudrim i umnim riječima obrati na Arjoka, zapovjednika kraljevskih straža, koji bijaše izišao da pogubi mudrace babilonske."},{"v":15,"t":"On reče Arjoku, zapovjedniku kraljevu: “Zašto je kralj izdao tako strogu naredbu?” Arjok pripovjedi Danielu,"},{"v":16,"t":"a Daniel otiđe kralju i zamoli da mu dade vremena te će kralju otkriti što san znači."},{"v":17,"t":"Daniel uđe u svoju kuću te sve kaza Hananiji, Mišaelu i Azarji, svojim drugovima,"},{"v":18,"t":"da mole milosrđe u Boga Nebeskoga radi te tajne, da Daniel i njegovi drugovi ne poginu s drugim mudracima babilonskim."},{"v":19,"t":"I objavi se tajna Danielu u noćnom viđenju. A Daniel blagoslovi Boga Nebeskoga."},{"v":20,"t":"Daniel prihvati riječ i reče: “Bilo ime Božje blagoslovljeno odvijeka dovijeka, njegova je mudrost i sila."},{"v":21,"t":"On mijenja doba i vremena, ruši i postavlja kraljeve, daje mudrost mudrima a znanje pronicavima."},{"v":22,"t":"On otkriva dubine i tajne, zna što je u tminama i svjetlost prebiva u njega."},{"v":23,"t":"Tebe, o Bože otaca mojih, slavim i hvalim što si mi dao mudrost i jakost! Evo, objavio si mi ono što smo te molili, objavio si nam što kralj traži.”"},{"v":24,"t":"Daniel ode k Arjoku, kome bijaše kralj naredio da smakne mudrace babilonske. Uđe i reče mu: “Ne ubijaj mudraca babilonskih! Odvedi me kralju, pa ću mu otkriti što san znači.”"},{"v":25,"t":"Arjok žurno odvede Daniela kralju i reče: “Našao sam među izgnanicima judejskim čovjeka koji će kralju kazati što san znači.”"},{"v":26,"t":"Kralj reče Danielu (koji se zvaše Baltazar): “Jesi li kadar kazati mi san koji sam usnio i što znači?”"},{"v":27,"t":"Daniel odgovori pred kraljem: “Tajnu koju istražuje kralj ne mogahu kralju otkriti mudraci, čarobnici, gataoci i zaklinjači;"},{"v":28,"t":"ali ima na nebu Bog koji objavljuje tajne i on je saopćio kralju Nabukodonozoru ono što će biti na svršetku dana. Evo tvoje sanje i onoga što ti se prividjelo na postelji:"},{"v":29,"t":"O kralju, na tvojoj ti postelji dođoše misli o tome što će se dogoditi kasnije, a Otkrivatelj tajna saopćio ti je ono što će biti."},{"v":30,"t":"Iako nemam mudrosti više nego ostali smrtnici, ta mi je tajna objavljena samo zato da njezino značenje saopćim kralju i da upoznaš misli svoga srca."},{"v":31,"t":"Ti si, o kralju, imao viđenje: gle, kip, golem kip, vrlo blistav, stajaše pred tobom, strašan za oči."},{"v":32,"t":"Tome kipu glava bijaše od čistog zlata, prsa i ruke od srebra, trbuh i bedra od mjedi,"},{"v":33,"t":"gnjati od željeza, a stopala dijelom od željeza, dijelom od gline."},{"v":34,"t":"Ti si promatrao: iznenada se odvali kamen a da ga ne dodirnu ruka, pa udari u kip, u stopala od željeza i gline te ih razbi."},{"v":35,"t":"Tada se smrvi najednom željezo i glina, mjed, srebro i zlato, i sve postade kao pljeva na gumnu ljeti i vjetar sve odnese bez traga. A kamen koji bijaše u kip udario postade veliko brdo te napuni svu zemlju."},{"v":36,"t":"To bijaše sanja; a njezino ćemo značenje reći pred kraljem.”"},{"v":37,"t":"“Ti, o kralju, kralju kraljeva, komu Bog Nebeski dade kraljevstvo, silu moć i slavu -"},{"v":38,"t":"i u čije je ruke stavio, gdje god se našli, sinove ljudske, životinje poljske, ptice nebeske i postavio te gospodarom nad svim time - ti si glava od zlata."},{"v":39,"t":"Poslije tebe ustat će drugo kraljevstvo, slabije od tvoga, pa treće, od mjedi, koje će gospodariti svom zemljom."},{"v":40,"t":"A četvrto kraljevstvo bit će tvrdo poput željeza, poput željeza koje sve satire i mrvi; kao željezo koje razbija, skršit će i razbit sva ona kraljevstva."},{"v":41,"t":"Stopala koja si vidio, dijelom glina a dijelom željezo, jesu podijeljeno kraljevstvo; imat će nešto od čvrstoće željeza prema onome što si vidio željezo izmiješano s glinom."},{"v":42,"t":"Prsti stopala, dijelom željezo a dijelom glina: kraljevstvo će biti dijelom čvrsto a dijelom krhko."},{"v":43,"t":"A što si vidio željezo izmiješano s glinom: oni će se miješati ljudskim sjemenom, ali se neće držati zajedno, kao što se ni željezo ne da pomiješati s glinom."},{"v":44,"t":"U vrijeme ovih kraljeva Bog Nebeski podići će kraljevstvo koje neće nikada propasti i neće prijeći na neki drugi narod. Ono će razbiti i uništiti sva ona kraljevstva, a samo će stajati dovijeka -"},{"v":45,"t":"kao što si vidio da se kamen s brijega odvalio a da ga ne dodirnu ruka te smrvio željezo, mjed, glinu, srebro i zlato. Veliki je Bog saopćio kralju što se ima dogoditi. Sanja je istinita, a tumačenje joj pouzdano.”"},{"v":46,"t":"Nato kralj Nabukodonozor pade ničice i pokloni se pred Danielom. Naredi da mu prinesu dar i kad."},{"v":47,"t":"I reče kralj Danielu: “Zaista, vaš je bog Bog nad bogovima i gospodar nad kraljevima, Otkrivatelj tajna, kad si mogao otkriti ovu tajnu.”"},{"v":48,"t":"Kralj uzvisi Daniela i dariva ga mnogim blistavim darovima. Postavi ga upraviteljem sve pokrajine babilonske i starješinom svih mudraca babilonskih."},{"v":49,"t":"Daniel zamoli kralja da odredi za upravitelje pokrajine babilonske Šadraka, Mešaka i Abed Nega, a Daniel ostade na kraljevu dvoru."}]},"3":{"hr":[{"v":1,"t":"Kralj Nabukodonozor odredi da se načini zlatni kip, visok šezdeset lakata i širok šest, i da ga postave u ravnici Duri, u pokrajini babilonskoj."},{"v":2,"t":"Kralj Nabukodonozor pozva satrape, namjesnike, upravitelje, savjetnike, rizničare, suce i zakonoznance i sve namjesnike pokrajina da dođu na posvetu kipa što ga podiže kralj Nabukodonozor."},{"v":3,"t":"Tada se sakupiše satrapi, namjesnici, upravitelji, savjetnici, rizničari, suci i zakonoznanci i svi namjesnici pokrajinske vlasti na posvetu kipa što ga podiže kralj Nabukodonozor. I stadoše pred kip što podiže Nabukodonozor."},{"v":4,"t":"Glasnik proglasi: “O narodi, plemena i jezici, evo što vam se naređuje:"},{"v":5,"t":"u času kad začujete zvuke roga, frule, citre, sambuke, psaltira, gajda i svakovrsnih drugih glazbala, bacite se na tlo i poklonite se zlatnome kipu što ga podiže kralj Nabukodonozor!"},{"v":6,"t":"Tko se ne baci na tlo i ne pokloni, bit će smjesta bačen u peć užarenu.”"},{"v":7,"t":"Zato, čim začuše zvuk roga, frule, citre, sambuke, psaltira, gajda i svakovrsnih drugih glazbala, baciše se na tlo svi narodi, plemena i jezici klanjajući se zlatnome kipu što ga podiže kralj Nabukodonozor."},{"v":8,"t":"Uto dođoše neki Kaldejci i optužiše Judejce."},{"v":9,"t":"Rekoše kralju Nabukodonozoru: “O kralju, živ bio dovijeka!"},{"v":10,"t":"Ti si, kralju, naredio svakom čovjeku koji začuje zvuke roga, frule, citre, sambuke, psaltira, gajda i svakovrsnih drugih glazbala da se baci na tlo i da se pokloni zlatnome kipu;"},{"v":11,"t":"a tko se ne baci na tlo i ne pokloni, da bude bačen u peć užarenu."},{"v":12,"t":"A evo, ovdje su Judejci koje si postavio za upravitelje pokrajine babilonske: Šadrak, Mešak i Abed Nego. Ti ljudi ne mare za te, o kralju; oni ne štuju tvojih bogova i nisu se poklonili zlatnome kipu što si ga podigao.”"},{"v":13,"t":"Nabukodonozor, bijesan i gnjevan, pozva Šadraka, Mešaka i Abed Nega. Odmah ih dovedoše pred kralja."},{"v":14,"t":"A Nabukodonozor im reče: “Je li istina, Šadrače, Mešače i Abed Nego, da vi ne štujete mojih bogova i da se ne klanjate zlatnome kipu što ga podigoh?"},{"v":15,"t":"Jeste li voljni, čim začujete zvuk roga, frule, citre, sambuke, psaltira, gajda i svakovrsnih drugih glazbala, baciti se na tlo i pokloniti se kipu što ga načinih? Ako li mu se ne poklonite, bit ćete smjesta bačeni u peć užarenu; i koji je taj bog koji bi vas izbavio iz ruke moje?”"},{"v":16,"t":"Šadrak, Mešak i Abed Nego odgovoriše kralju Nabukodonozoru: “Ne treba da ti odgovorimo na to."},{"v":17,"t":"Bog naš, kome služimo, može nas izbaviti iz užarene peći i od ruke tvoje, kralju; on će nas i izbaviti."},{"v":18,"t":"No ako toga i ne učini, znaj, o kralju: mi nećemo služiti tvojemu bogu niti ćemo se pokloniti kipu što si ga podigao.”"},{"v":19,"t":"Na te riječi kralj Nabukodonozor uskipje bijesom, a lice mu se iznakazi na Šadraka, Mešaka i Abed Nega."},{"v":20,"t":"On naredi da se peć ugrije sedam puta jače no inače i jakim ljudima iz svoje vojske zapovjedi da svežu Šadraka, Mešaka i Abed Nega i bace u peć punu žarkoga ognja."},{"v":21,"t":"Svezaše ih, dakle, i u plaštevima, obući i kapama baciše u zažarenu peć."},{"v":22,"t":"Kako kraljeva zapovijed bijaše žurna a peć preko mjere užarena, plamen ubi ljude koji su bacali Šadraka, Mešaka i Abed Nega."},{"v":23,"t":"A tri čovjeka - Šadrak, Mešak i Abed Nego - padoše svezani u zažarenu peć."},{"v":24,"t":"I hodahu posred plamena hvaleći Boga, slaveći Gospoda."},{"v":25,"t":"Stavši Azarja otvori usta i pomoli se usred ognja ovako:"},{"v":26,"t":"“Blagoslovljen i hvaljen budi, Gospode, Bože otaca naših, i neka ime tvoje bude slavljeno dovijeka!"},{"v":27,"t":"Pravedan si u svemu što učini nama, sva su tvoja djela istinita, svi tvoji putovi pravi, svi tvoji sudovi istina."},{"v":28,"t":"Po pravdi si presudio u svemu što si poslao na nas i na sveti grad otaca naših, Jeruzalem: zbog naših si grijeha ovako postupio s nama, u istini i pravednosti."},{"v":29,"t":"Zgriješili smo i počinili bezakonje odmetnuvši se od tebe, sagriješili teško; ne slušasmo naredbe tvoje."},{"v":30,"t":"Nismo ih čuvali i nismo vršili što nam bijaše naređeno za naše dobro."},{"v":31,"t":"Sve što si poslao na nas, sve što si nam učinio, pravedno si učinio."},{"v":32,"t":"Kad si nas predao u ruke bezakonika, dušmana naših, najgorih odmetnika, i kralju nepravednom, najgorem na zemlji,"},{"v":33,"t":"te danas ne smijemo otvoriti usta: sramota i ruglo pokrivaju one koji ti služe i tebi se klanjaju."}]},"4":{"hr":[{"v":1,"t":"Ja, Nabukodonozor, življah mirno u svojoj kući i sretno u svojoj palači,"},{"v":2,"t":"kad vidjeh sanju koja me uplašila. Utvare i viđenja što su mi se na mom ležaju vrzla po glavi uznemiriše me."},{"v":3,"t":"I naredih: neka mi pozovu sve mudrace babilonske da mi kažu što sanja znači."},{"v":4,"t":"Dođoše gataoci, čarobnici, zvjezdari i tumači znakova: ja im rekoh svoju sanju, a oni mi ne znadoše reći njezino značenje."},{"v":5,"t":"Tada dođe preda me Daniel, koji je nazvan Baltazar prema imenu moga boga, i u komu prebiva duh Boga Svetoga. Ja mu pripovjedih svoju sanju:"},{"v":6,"t":"“Baltazare, starješino gatalaca, znam da u tebi prebiva duh Boga Svetoga i da ti nijedna tajna nije preteška: evo sanje što je imah: daj mi njezino značenje."},{"v":7,"t":"Evo viđenja što mi se na postelji vrzlo po glavi: Pogledam, kad evo jedno stablo usred zemlje vrlo veliko."},{"v":8,"t":"Stablo poraste, postade snažno, visina mu doseže nebo, vidjelo se s krajeva zemlje."},{"v":9,"t":"Krošnja mu bijaše lijepa, plodovi obilni; na njemu je bilo hrane za sve, u njegovoj sjeni počivaše zvijerje poljsko, na njegovim se granama gnijezdile ptice nebeske i svako se tijelo hranilo od njega."},{"v":10,"t":"Ja promatrah viđenja što su mi se na mojoj postelji vrzla po glavi kad, evo, Stražar, Svetac, silazi s neba,"},{"v":11,"t":"silnim glasom viče: 'Posijecite stablo, okrešite mu grane, počupajte mu lišće, pobacajte plodove! Neka se životinje razbjegnu ispod njega i ptice s grana njegovih!"},{"v":12,"t":"U zemlji ostavite panj i korijenje u gvozdenim i mjedenim okovima, u travi poljskoj! Neka ga pere rosa nebeska, i travu zemaljsku neka dijeli sa zvijerjem poljskim!"},{"v":13,"t":"Neka mu se promijeni srce čovječje, srce životinjsko nek' mu se dade! Sedam vremena neka prođe nad njim!"},{"v":14,"t":"Tako su presudili Stražari, tako su odlučili Sveci, da sve živo upozna kako Svevišnji ima vlast nad kraljevstvom ljudskim: on ga daje kome hoće i postavlja nad njim najnižega od ljudi!'"},{"v":15,"t":"Ovo je sanja što je vidjeh ja, kralj Nabukodonozor. A ti, Baltazare, reci mi njezino značenje, jer mi nijedan od mudraca moga kraljevstva to ne može reći; ti možeš, jer u tebi je duh Boga Svetoga.”"},{"v":16,"t":"Tada se Daniel, nazvan Baltazar, načas smete i prestraši u svojim mislima. Kralj reče: “Baltazare, ne daj se zbuniti ovom sanjom i njezinim značenjem!” Baltazar odgovori: “Gospodaru moj, ova sanja neka bude tvojim dušmanima i njezino značenje tvojim mrziteljima!"},{"v":17,"t":"Stablo koje si vidio, veliko i snažno, koje seže sve do neba i vidi se po svoj zemlji,"},{"v":18,"t":"krošnje lijepe i plodova obilnih na kojem bijaše hrane za sve i pod kojim počiva zvijerje poljsko, a na njegovim se granama gnijezde ptice nebeske:"},{"v":19,"t":"to si ti, o kralju, koji si velik i moćan, veličina ti se povećala i dosegla do neba, a tvoja vlast do krajeva zemlje."},{"v":20,"t":"A što je vidio kralj kako Stražar, Svetac, silazi s neba te govori: 'Posijecite stablo, raskomadajte ga, no njegov panj i korijenje ostavite u zemlji, u gvozdenim i mjedenim okovima, u travi poljskoj, neka ga pere rosa nebeska i dio neka mu bude sa zvijerjem poljskim dok ne prođe sedam vremena nad njim' -"},{"v":21,"t":"ovo je značenje, o kralju, odluka Svevišnjega što će se ispuniti na mom gospodaru kralju:"},{"v":22,"t":"Izagnat će te iz društva ljudi i sa životinjama ćeš poljskim boraviti; hranit ćeš se travom kao goveda, tebe će prati rosa nebeska; sedam će vremena proći nad tobom dok ne upoznaš da Svevišnji ima vlast nad kraljevstvom ljudskim i da ga daje kome on hoće."},{"v":23,"t":"A što se reklo 'Ostavite panj i korijenje stabla' - tvoje će se kraljevstvo obnoviti čim spoznaš da Nebesa imaju svu vlast."},{"v":24,"t":"Zato, kralju, neka ti bude mio moj savjet: iskupi svoje grijehe pravednim djelima i svoja bezakonja milosrđem prema siromasima, da bi ti potrajala sreća.”"},{"v":25,"t":"Sve se to dogodi kralju Nabukodonozoru."},{"v":26,"t":"Dvanaest mjeseci kasnije, šetajući babilonskim kraljevskim dvorom,"},{"v":27,"t":"kralj govoraše: “Nije li to taj veliki Babilon što ga ja sagradih da mi bude kraljevskom prijestolnicom - snagom svoje moći, na slavu svoga veličanstva?”"},{"v":28,"t":"Još bijahu te riječi u ustima njegovim kad s neba dođe glas: “Tebi se objavljuje, kralju Nabukodonozore! Kraljevstvo ti se oduzelo;"},{"v":29,"t":"bit ćeš izagnan iz društva ljudi, sa životinjama ćeš poljskim boraviti; hranit ćeš se travom kao goveda, i sedam će vremena proći nad tobom dok ne spoznaš da Svevišnji ima vlast nad kraljevstvom ljudskim, i da ga on daje kome hoće.”"},{"v":30,"t":"I smjesta se riječ izvrši na Nabukodonozoru: bi izagnan iz društva ljudi, jeđaše travu kao goveda, prala ga rosa nebeska; vlasi mu narastoše poput orlova perja, a njegovi nokti kao ptičje pandže."},{"v":31,"t":"“Pošto se navršiše određeni dani, ja, Nabukodonozor, podigoh oči prema nebu, razum mi se vrati, tada blagoslovih Svevišnjega hvaleći i uzvisujući onoga koji živi dovijeka: njegovo je kraljevstvo - kraljevstvo vječno, njegova je vlast za sva pokoljenja."},{"v":32,"t":"Stanovnici zemlje - upravo kao da ih i nema: po svojoj volji postupa on s vojskom nebeskom i sa žiteljima zemaljskim. Nitko ne može zaustaviti njegovu ruku ili mu kazati: 'Što to radiš?'"},{"v":33,"t":"U isti čas razum mi se vrati, i na slavu moje kraljevske časti vrati mi se veličanstvo i sjaj; moji me savjetnici i velikaši potražiše, bih uspostavljen u kraljevsku čast i moja veličina još poraste."},{"v":34,"t":"Sada ja, Nabukodonozor, hvalim, uzvisujem i slavim Kralja nebeskoga, čija su sva djela istina, svi putovi pravda i koji može poniziti one koji hode u oholosti.”"}]},"5":{"hr":[{"v":1,"t":"Kralj Baltazar priredi veliku gozbu tisući svojih velikaša; s njima je pio vino."},{"v":2,"t":"Opijen vinom, Baltazar naredi da se donese zlatno i srebrno suđe koje njegov otac Nabukodonozor bijaše oteo iz jeruzalemskog Svetišta, pa da iz njega pije kralj, njegovi velikaši, njegove žene i suložnice."},{"v":3,"t":"Donesoše dakle zlatno i srebrno suđe oteto iz Božjega doma u Jeruzalemu i stadoše piti iz njega kralj i njegovi velikaši, njegove žene i suložnice."},{"v":4,"t":"Pili su vino i slavili svoje bogove od zlata i srebra, mjedi i željeza, drva i kamena."},{"v":5,"t":"Iznenada se pojaviše prsti čovječje ruke koji stadoše pisati, nasuprot velikom svijećnjaku, po okrečenu zidu kraljevskog dvora, i kralj vidje dlan ruke koja pisaše."},{"v":6,"t":"Kralj problijedje, misli ga uznemiriše, zglobovi njegovih kukova popustiše i koljena mu stadoše udarati jedno o drugo."},{"v":7,"t":"Glasno dozva čarobnike, zvjezdare i gataoce. I reče kralj mudracima babilonskim: “Tko pročita ovo pismo i otkrije mi njegov smisao, bit će obučen u grimiz, oko vrata nosit će zlatan lanac i bit će treći u kraljevstvu.”"},{"v":8,"t":"Pristupe svi mudraci kraljevi, ali ne mogoše pročitati pismo niti mu otkriti značenje."},{"v":9,"t":"Kralj se Baltazar zbog toga silno uplaši, problijedje, a njegovi velikaši ostadoše zbunjeni."},{"v":10,"t":"Kraljica, čuvši riječi kralja i velikaša, uđe u gozbenu dvoranu i reče: “Kralju, živ bio dovijeka! Neka se tvoje misli ne uznemiruju i tvoje lice neka ne blijedi!"},{"v":11,"t":"Ima u tvome kraljevstvu čovjek u kome prebiva duh Boga Svetoga. Još za vremena tvoga oca nađe se u njemu svjetlo, razum i mudrost slična mudrosti bogova. I zato ga kralj Nabukodonozor, otac tvoj, imenova starješinom čarobnika, gatalaca, zvjezdara i mudraca."},{"v":12,"t":"Budući da se u tom Danielu - koga kralj bijaše nazvao Baltazarom - našao duh izvanredan, znanje, bistrina, vještina da tumači sanje, da rješava zagonetke i da razrješuje teškoće, pozovi stoga Daniela i on će ti kazati značenje.”"},{"v":13,"t":"Dovedoše Daniela pred kralja, a kralj ga upita: “Jesi li ti Daniel, jedan od izgnanika judejskih koje dovede iz Judeje kralj moj otac?"},{"v":14,"t":"Čujem da duh Božji prebiva na tebi i da je u tebi svjetlo, razum i mudrost izvanredna."},{"v":15,"t":"Dovedoše mi mudrace i čarobnike da pročitaju ovo pismo i da mi reknu njegovo značenje, ali oni nisu kadri otkriti mi njegov smisao."},{"v":16,"t":"A čujem da si ti kadar dati tumačenja i da razrješuješ teškoće. Ako si dakle kadar pročitati ovo pismo i reći mi njegovo značenje, bit ćeš odjeven u grimiz i nosit ćeš zlatan lanac oko vrata i bit ćeš treći u kraljevstvu.”"},{"v":17,"t":"Daniel prihvati riječ i odgovori kralju: “Tvoji darovi neka ti ostanu, i svoje poklone daj drugima! A ja ću pročitati ovo pismo kralju i kazat ću mu njegovo značenje."},{"v":18,"t":"O kralju, Bog je Svevišnji dao kraljevstvo, veličinu, veličanstvo i slavu Nabukodonozoru, ocu tvome."},{"v":19,"t":"Zbog veličine koju mu bijaše dao drhtahu od straha pred njim narodi, plemena i jezici: on ubijaše po svojoj volji, ostavljaše na životu koga je htio, uzdizaše koga je htio, ponizivaše koga je htio."},{"v":20,"t":"No kad mu se srce uzdiglo i duh uzobijestio do drskosti, tada bi oboren sa svoga kraljevskog prijestolja i slava mu bijaše oduzeta."},{"v":21,"t":"Bi izagnan iz ljudskog društva i srce mu posta slično životinjskom: prebivaše s divljim magarcima; poput goveda jeđaše travu; nebeska je rosa prala njegovo tijelo, dok ne spozna da Svevišnji Bog ima vlast nad kraljevstvom ljudskim i stavlja mu na čelo onoga koga on hoće."},{"v":22,"t":"No ti, Baltazare, sine njegov, nisi ponizio srce svoje, iako si znao sve ovo:"},{"v":23,"t":"ti si se podigao protiv Gospoda Nebeskoga, dao si da ti donesu suđe iz njegova Doma i pili ste vino iz njega ti, tvoji velikaši, tvoje žene i tvoje suložnice, hvaleći bogove od zlata i srebra, od mjedi i željeza, od drva i kamena, koji ne vide, ne čuju niti razumiju, a nisi dao slavu Bogu koji u svojoj ruci drži dah tvoj i sve tvoje putove."},{"v":24,"t":"I zato on posla ovu ruku koja napisa ovo pismo.”"},{"v":25,"t":"“A evo što je napisano: Mene, Mene, Tekel, Parsin."},{"v":26,"t":"A te riječi znače: Mene: izmjerio je Bog tvoje kraljevstvo i učinio mu kraj;"},{"v":27,"t":"Tekel: bio si vagnut na tezulji i nađen si prelagan;"},{"v":28,"t":"Parsin: razdijeljeno je tvoje kraljevstvo i predano Medijcima i Perzijancima.”"},{"v":29,"t":"Tada Baltazar naredi da Daniela obuku u grimiz, da mu oko vrata objese zlatan lanac i da ga proglase trećim u kraljevstvu."},{"v":30,"t":"Iste te noći kaldejski kralj Baltazar bi ubijen."}]},"6":{"hr":[{"v":1,"t":"A Darije Medijac preuze kraljevstvo, star već šezdeset i dvije godine."},{"v":2,"t":"Svidjelo se Dariju da postavi nad svojim kraljevstvom stotinu i dvadeset satrapa da budu nad svim kraljevstvom."},{"v":3,"t":"Njima na čelo stavi tri pročelnika - Daniel bijaše jedan od njih - kojima će satrapi polagati račun da se ne bi dosađivalo kralju."},{"v":4,"t":"Daniel se toliko isticaše svojim izvanrednim duhom iznad pročelnika i satrapa te kralj mišljaše da ga postavi nad svim kraljevstvom."},{"v":5,"t":"Tada pročelnici i satrapi stadoše tražiti povod, štogod oko državne uprave, zbog čega bi mogli optužiti Daniela; ali ne mogoše na njemu naći ništa takvo, ništa zbog čega bi ga prekorili, jer bijaše vjeran, na njemu ni nemara ni ogrešenja."},{"v":6,"t":"Ti ljudi rekoše tada: “Nećemo naći nikakva povoda protiv Daniela, osim da nađemo nešto protiv njega u zakonu njegova Boga.”"},{"v":7,"t":"Tada pročelnici i satrapi navališe na kralja te mu rekoše: “O kralju Darije, živ bio dovijeka!"},{"v":8,"t":"Svi pročelnici kraljevstva, predstojnici i satrapi, savjetnici i namjesnici složiše se u tome da bi trebalo da kralj izda naredbu i zabranu: svaki onaj koji bi u roku od trideset dana upravio molbu bilo na kojega boga ili čovjeka, osim na tebe, o kralju, bit će bačen u lavsku jamu."},{"v":9,"t":"O kralju, potvrdi tu zabranu i potpiši naredbu da bude neopoziva prema nepromjenljivom medijsko-perzijskom zakonu!”"},{"v":10,"t":"Nato kralj Darije potpisa pismo i zabranu."},{"v":11,"t":"Saznavši Daniel da je spis potpisan, otiđe u svoju kuću. Prozori gornje sobe bijahu otvoreni prema Jeruzalemu. Tu je on tri puta na dan padao na koljena blagoslivljajući, moleći i hvaleći Boga, kako je uvijek činio."},{"v":12,"t":"Oni ljudi nahrupiše i nađoše Daniela gdje moli i zaziva svoga Boga."},{"v":13,"t":"Tada odoše i pred kraljem se pozvaše na kraljevsku zabranu: “Zar ti nisi potpisao zabranu prema kojoj će svaki onaj koji bi u vremenu od trideset dana upravio molbu na nekoga boga ili čovjeka, osim na tebe, o kralju, biti bačen u lavsku jamu?” Kralj odgovori: “Tako je odlučeno po nepromjenljivom medijsko-perzijskom zakonu.”"},{"v":14,"t":"Tada rekoše kralju: “Daniel, onaj od izgnanika judejskih, ne mari za tebe, o kralju, ni za tvoju zabranu koju si potpisao: tri puta na dan obavlja svoju molitvu.”"},{"v":15,"t":"Čuvši te riječi, kralj se vrlo ražalosti i odluči spasiti Daniela. Sve do sunčeva zalaza nastojaše da ga spasi."},{"v":16,"t":"Ali oni ljudi navališe na kralja govoreći: “Znaj, o kralju, da prema medijsko-perzijskom zakonu nijedna kraljevska zabrana ili odluka ne može biti opozvana!”"},{"v":17,"t":"Tada kralj naredi da dovedu Daniela i da ga bace u lavsku jamu. Kralj reče Danielu: “Bog tvoj, kome tako postojano služiš, neka te izbavi.”"},{"v":18,"t":"Donesoše kamen i staviše ga jami na otvor. Kralj ga zapečati prstenom svojim i prstenom svojih velikaša, da se ništa ne mijenja za Daniela."},{"v":19,"t":"Kralj se vrati u svoj dvor i provede noć ne okusivši jela i ne dopustivši da mu dovedu suložnice. Nije mogao usnuti."},{"v":20,"t":"Kralj ustade u ranu zoru, kad se danilo, i pođe brzo k lavskoj jami."},{"v":21,"t":"Kad se primače blizu, viknu žalosnim glasom Danielu: “Daniele, slugo Boga živoga, je li te Bog, kome postojano služiš, mogao izbaviti od lavova?”"},{"v":22,"t":"Daniel odgovori: “O kralju, živ bio dovijeka!"},{"v":23,"t":"Moj je Bog poslao svog Anđela; zatvorio je ralje lavovima te mi ne naudiše, jer sam nedužan pred njim. Pa i pred tobom, o kralju, ja sam bez krivice.”"},{"v":24,"t":"Kralj se vrlo obradova i naredi da Daniela izvade iz jame. Izvadiše Daniela iz jame neozlijeđena, jer se bijaše uzdao u svoga Boga."},{"v":25,"t":"Kralj zapovjedi da dovedu one ljude koji bijahu optužili Daniela i da ih bace u lavsku jamu - njih, njihove žene i njihovu djecu: i prije nego dodirnuše tlo, lavovi ih zgrabiše i smrviše im kosti."},{"v":26,"t":"Nato kralj Darije napisa svim plemenima, narodima i jezicima što stanuju po svoj zemlji: “Obilovali mirom!"},{"v":27,"t":"Evo naredbe koju donosim: u svemu mojem kraljevstvu neka se ljudi boje i neka dršću pred Bogom Danielovim: On je Bog živi, on ostaje dovijeka! Njegovo kraljevstvo neće propasti, njegovoj vlasti nema kraja!"},{"v":28,"t":"On izbavlja i spasava, čini znake i čudesa na nebesima i na zemlji! On je spasio Daniela iz šapa lavljih!”"},{"v":29,"t":"Daniel bijaše sretan za vladanja Darija i za vladanja Kira Perzijanca."}]},"7":{"hr":[{"v":1,"t":"Prve godine Baltazara, kralja babilonskoga, usni Daniel san: utvare mu se na postelji vrzle glavom. Sažeto zapisa što je usnio."},{"v":2,"t":"Kazivaše ovako: Noću u viđenju pogledah, kad eno: četiri vjetra nebeska uzbibaše veliko more."},{"v":3,"t":"Četiri goleme nemani iziđoše iz mora, svaka drukčija. Prva bijaše kao lav, a krila joj orlovska."},{"v":4,"t":"Dok je promatrah, krila joj se iščupaše, diže se ona sa zemlje i uspravi na noge kao čovjek, i bijaše joj dano srce čovječje."},{"v":5,"t":"Kad eno druga neman: gle, sasvim drukčija: kao medvjed, s jedne strane uspravljena, tri joj rebra u raljama, među zubima. I bijaše joj rečeno: “Ustani, nažderi se mesa!”"},{"v":6,"t":"Gledah dalje, i evo: treća neman kao leopard, na leđima joj četiri ptičja krila: imaše četiri glave, i dana joj je moć."},{"v":7,"t":"Zatim, u noćnim viđenjima, pogledah, kad eno: četvrta neman, strahovita, užasna, izvanredno snažna: imaše velike gvozdene zube; ona žderaše, mrvljaše, a što preostade, gazila je nogama. Razlikovala se od prijašnjih nemani i imaše deset rogova."},{"v":8,"t":"Promatrah joj rogove, i gle: među njima poraste jedan mali rog; i pred tim se rogom iščupaše tri prijašnja roga. I gle, na tome rogu oči kao oči čovječje i usta koja govorahu velike hule."},{"v":9,"t":"Gledao sam: Prijestolja bjehu postavljena i Pradavni sjede. Odijelo mu bijelo poput snijega; vlasi na glavi kao čista vuna. Njegovo prijestolje kao plamenovi ognjeni i točkovi kao žarki oganj."},{"v":10,"t":"Rijeka ognjena tekla, izvirala ispred njega. Tisuću tisuća služahu njemu, mirijade stajahu pred njim. Sud sjede, knjige se otvoriše."},{"v":11,"t":"Ja gledah tada, zbog buke velikih hula što ih govoraše rog, i dok gledah, neman bi ubijena, njezino tijelo raskomadano i predano ognju."},{"v":12,"t":"Ostalim nemanima vlast bi oduzeta, ali im duljina života bi na jedno vrijeme i rok."},{"v":13,"t":"Gledah u noćnim viđenjima i gle, na oblacima nebeskim dolazi kao Sin čovječji. On se približi Pradavnome i dovedu ga k njemu."},{"v":14,"t":"Njemu bi predana vlast, čast i kraljevstvo, da mu služe svi narodi, plemena i jezici. Vlast njegova vlast je vječna i nikada neće proći, kraljevstvo njegovo neće propasti."},{"v":15,"t":"Meni, Danielu, smete se zbog toga sav duh, viđenja mi se vrzoše glavom, svega me prestraviše."},{"v":16,"t":"Pristupih jednome od onih koji stajahu ondje i zamolih ga da mi rekne istinu o svemu tome. On mi odgovori i kaza mi značenje:"},{"v":17,"t":"“One četiri goleme nemani jesu četiri kralja koji će se dići na zemlji."},{"v":18,"t":"Ali će od njih kraljevstvo preuzeti Sveci Svevišnjega i oni će ga posjedovati za vijeke vjekova.”"},{"v":19,"t":"Zaželjeh tada saznati istinu o četvrtoj nemani, onoj koja se razlikovaše od svih drugih, bila izvanredno strašna, imala gvozdene zube i mjedene pandže i koja je žderala i mrvila i nogama gazila što preostajaše;"},{"v":20,"t":"i o deset rogova što bijahu na njezinoj glavi, i o drugom rogu koji poraste dok tri prva otpadoše - o rogu koji imaše oči i usta što govorahu velike hule i koji bijaše veći nego drugi rogovi."},{"v":21,"t":"I gledao sam kako ovaj rog ratuje protiv Svetaca te ih nadvladava,"},{"v":22,"t":"dok ne dođe Pradavni, koji dosudi pravdu Svecima Svevišnjega, i dok ne dođe vrijeme kad Sveci zaposjedoše kraljevstvo."},{"v":23,"t":"On reče: “Četvrta neman bit će četvrto kraljevstvo na zemlji, različito od svih kraljevstava. Progutat će svu zemlju, zgazit' je i smrviti."},{"v":24,"t":"A deset rogova: Od ovoga kraljevstva nastat će deset kraljeva, a iza njih će se podići jedan drugi različit od onih prvih - i oborit će tri kralja."},{"v":25,"t":"On će huliti na Svevišnjega, zatirati Svece Svevišnjega; pomišljat će da promijeni blagdane i Zakon, i Sveci će biti predani u njegove ruke na jedno vrijeme i dva vremena i polovinu vremena."},{"v":26,"t":"Tada će sjesti Sud, vlast mu oduzeti, razoriti, sasvim uništiti."},{"v":27,"t":"A kraljevstvo, vlast i veličanstvo pod svim nebesima dat će se puku Svetaca Svevišnjega. Kraljevstvo njegovo kraljevstvo je vječno, i sve vlasti služit će mu i pokoravati se njemu.”"},{"v":28,"t":"Ovdje se završava izvještaj. Ja, Daniel, bijah vrlo potresen u svojim mislima i lice mi problijedje, ali sve ovo sačuvah u srcu svojemu."}]},"8":{"hr":[{"v":1,"t":"Treće godine kralja Baltazara ukaza se meni, Danielu, viđenje poslije onoga koje mi se ukazalo prije."},{"v":2,"t":"Gledah viđenje, i dok gledah, nađoh se u Šušanu, čvrstu gradu u pokrajini Elamu; i u viđenju se vidjeh na rijeci Ulaju."},{"v":3,"t":"Podigoh oči, i gle: ovan stajaše kraj rijeke. Imaše dva roga: oba roga visoka, no jedan viši nego drugi, a onaj viši narastao poslije."},{"v":4,"t":"Gledah kako ovan bode na zapad, na sjever i jug. Nijedna mu se životinja ne mogaše oprijeti, ništa mu ne mogaše izbjeći. Činio je što je htio, osilio se."},{"v":5,"t":"Dok sam promatrao, gle: jarac dolazi sa zapada povrh sve zemlje, ne dodirujući tla; jarac imaše silan rog među očima."},{"v":6,"t":"Približi se dvorogom ovnu kojega bijah vidio gdje stoji kraj rijeke i potrča na njega u svoj žestini svoje snage."},{"v":7,"t":"Vidjeh kako se približi ovnu: bijesno udari na ovna i slomi mu oba roga, a ovan nije imao snage da mu se opre; obori ga jarac na zemlju i stade ga nogama gaziti; nikoga ne bijaše da spasi ovna."},{"v":8,"t":"Jarac osili veoma, ali kad osili, veliki se rog slomi, a na njegovu mjestu izrastoše četiri velika roga prema četiri vjetra nebeska."},{"v":9,"t":"Iz jednoga od njih izbi malen rog, ali taj silno poraste prema jugu i istoku, prema Divoti."},{"v":10,"t":"On poraste sve do Nebeske vojske, obori na zemlju neke iz Vojske i od zvijezda pa ih zgazi nogama."},{"v":11,"t":"Poraste sve do Zapovjednika Vojske, oduze mu svagdašnju žrtvu i razori mu njegovo Sveto mjesto."},{"v":12,"t":"Vojska se digla na žrtvu svagdašnju zbog opačine, na zemlju oborila istinu i uspje u svemu što činjaše."},{"v":13,"t":"Tada čuh gdje jedan Svetac govori, a drugi Svetac upita onoga koji govoraše: “Dokle će trajati ovo viđenje o svagdašnjoj žrtvi i o opačini što pustoši i gazi Svetište i Vojsku?”"},{"v":14,"t":"Odgovori: “Još dvije tisuće i tri stotine večeri i jutara; tada će Svetište biti očišćeno.”"},{"v":15,"t":"Kad sam ja, Daniel, gledajući ovo viđenje, tražio da ga razumijem, gle, preda me stade kao neki čovjek."},{"v":16,"t":"Začuh glas čovječji gdje viče preko Ulaja: “Gabriele, objasni mu to viđenje!”"},{"v":17,"t":"On pođe onamo gdje stajah i kad mi se približi, strah me obuze i padoh na lice. On mi reče: “Sine čovječji, razumij: jer ovo je viđenje za vrijeme posljednje.”"},{"v":18,"t":"On još govoraše, a ja se onesvijestih, padoh na zemlju. On me dotače i uspravi na mom mjestu."},{"v":19,"t":"I reče: “Evo, kazat ću ti što će doći na kraju gnjeva, najavljeni svršetak."},{"v":20,"t":"Ovan što si ga vidio - njegova dva roga - to su kraljevi Medije i Perzije."},{"v":21,"t":"Rutavi jarac jest kralj Grčke; veliki rog među njegovim očima jest prvi kralj;"},{"v":22,"t":"slomljeni rog i četiri roga što izbiše na njegovu mjestu, to su četiri kraljevstva što će izići iz njegova naroda, ali neće imati njegovu moć."},{"v":23,"t":"I potkraj njihova kraljevanja, kad bezakonici navrše mjeru, ustat će kralj, drzak i lukav."},{"v":24,"t":"Njegova će moć porasti, ali ne svojom snagom; nesmiljeno će pustošiti, uspijevat će u svojim pothvatima, zatirat' junake i narod Svetaca."},{"v":25,"t":"Zbog njegove lukavosti prijevara će uspijevati u njegovoj ruci. On će se uznijeti u svome srcu, iz čista mira upropastit će mnoge. Suprotstavit će se Knezu nad knezovima, ali će - ne rukom - biti skršen."},{"v":26,"t":"Viđenje o večerima i jutrima o kojem je bilo govora istinito je; no ti ga zapečati, jer je za daleke dane.”"},{"v":27,"t":"Tada ja, Daniel, obnemogoh i bijah bolestan više dana. Zatim ustadoh da vršim kraljevske poslove. Bijah smeten zbog viđenja, no nitko to nije dokučio."}]},"9":{"hr":[{"v":1,"t":"Prve godine Darija, sina Artakserksova, iz roda Medijaca, koji vladaše kraljevstvom kaldejskim,"},{"v":2,"t":"prve dakle godine njegova kraljevanja, ja, Daniel, istraživah u Pismima broj godina koje se - prema riječi koju Jahve uputi proroku Jeremiji - imaju ispuniti nad ruševinama Jeruzalema: sedamdeset godina."},{"v":3,"t":"Ja obratih svoje lice prema Gospodinu Bogu nastojeći moliti se i zaklinjati u postu, kostrijeti i pepelu."},{"v":4,"t":"Ja se moljah Jahvi, Bogu svome, priznavajući: “Ah, Gospodine moj, Bože veliki i strahoviti, koji čuvaš Savez i naklonost onima koji tebe ljube i čuvaju zapovijedi tvoje!"},{"v":5,"t":"Mi sagriješismo, mi bezakonje počinismo, zlo učinismo, odmetnusmo se i udaljismo od zapovijedi i naredaba tvojih."},{"v":6,"t":"Nismo slušali sluge tvoje, proroke koji govorahu u tvoje ime našim kraljevima, našim knezovima, našim očevima, svemu puku zemlje."},{"v":7,"t":"U tebe je, Gospodine, pravednost, a u nas stid na obrazu, kao u ovaj dan, u nas Judejaca, Jeruzalemaca, svega Izraela, blizu i daleko, u svim zemljama kuda si ih rastjerao zbog nevjernosti kojom ti se iznevjeriše."},{"v":8,"t":"Jahve, stid na obraz nama, našim kraljevima, našim knezovima, našim očevima, jer sagriješismo protiv tebe!"},{"v":9,"t":"U Gospoda je Boga našega smilovanje i oproštenje jer smo se odmetnuli od njega"},{"v":10,"t":"i nismo slušali glas Jahve, Boga našega, da slijedimo njegove zakone što nam ih dade po svojim slugama, prorocima."},{"v":11,"t":"Sav je Izrael prestupio Zakon tvoj, odmetnuo se ne slušajući tvoj glas. Zato se na nas izlila kletva i prokletstvo, kako je zapisano u Zakonu Mojsija, sluge Božjega - jer sagriješismo protiv Njega."},{"v":12,"t":"Izvršio je prijetnje kojima je zaprijetio nama i sucima koji su nam sudili: svalio je na nas tešku nesreću te se ne dogodi pod nebom što se dogodi u Jeruzalemu."},{"v":13,"t":"Sva ova nesreća, kao što je zapisano u Zakonu Mojsijevu, došla je na nas, a mi nismo umilostivili lice Jahve, Boga svojega: nismo se obratili od svojih bezakonja pa da prionemo uz istinu tvoju."},{"v":14,"t":"Jahve je bdio nad nesrećom, on je dovede na nas. Jer je pravedan Jahve, Bog naš, u svim djelima koja učini, a mi nismo slušali glas njegov."},{"v":15,"t":"A sada, Gospode, Bože naš, koji si moćnom svojom rukom izveo narod svoj iz zemlje egipatske - i time sebi stekao ime koje traje do danas: mi sagriješismo, mi zlo učinismo."},{"v":16,"t":"Gospode, po svoj pravednosti svojoj odvrati svoj gnjev i svoju jarost od Jeruzalema, grada svojega, Svete gore svoje, jer zbog naših grijeha i zlodjela naših otaca Jeruzalem i tvoj narod ruglo su svima koji nas okružuju.”"},{"v":17,"t":"“A sada poslušaj, o Bože naš, molitvu sluge svoga i usrdne molbe njegove. Neka tvoje lice zasja nad svetištem tvojim opustošenim - zbog tebe, Gospode!"},{"v":18,"t":"Prikloni uho svoje, Bože moj, i slušaj! Otvori oči te pogledaj našu pustoš i grad koji se tvojim zove imenom! Jer mi te ne molimo zbog svoje pravednosti, već zbog velikih smilovanja tvojih."},{"v":19,"t":"Gospode, čuj! Gospode, oprosti! Gospode, poslušaj i čini! Ne oklijevaj - zbog sebe, Bože moj, jer se tvojim imenom zove grad tvoj i narod tvoj!”"},{"v":20,"t":"Ja sam još govorio, moleći se i priznavajući grijehe svoje i grijehe svog naroda Izraela i usrdno zaklinjući Jahvu, svoga Boga, za Svetu goru Boga svoga."},{"v":21,"t":"Dok sam dakle ja još govorio moleći se, onaj čovjek Gabriel, koga vidjeh na početku viđenja, doletje u brzu letu, dotače me se u vrijeme večernjeg prinosa"},{"v":22,"t":"i pouči me: “Daniele, evo me: dođoh da te poučim."},{"v":23,"t":"Od početka tvoje molitve izišla je riječ, i ja dođoh da ti je navijestim. Ti si miljenik. Pazi dobro na riječ, razumij viđenje.”"},{"v":24,"t":"“Sedamdeset je sedmica određeno tvom narodu i tvom svetom gradu da se dokrajči opačina, da se stavi pečat grijehu, da se zadovolji za bezakonje, da se uvede vječna pravednost, da se stavi pečat viđenju i prorocima, da se pomaže Sveti nad svetima."},{"v":25,"t":"Znaj i razumij: Od časa kad izađe riječ 'Neka se vrate i neka opet sagrade Jeruzalem' pa do Kneza Pomazanika: sedam sedmica, a onda šezdeset i dvije sedmice, i bit će opet sagrađeni trg i opkop, i to u teško vrijeme."},{"v":26,"t":"A poslije šezdeset i dvije sedmice bit će Pomazanik pogubljen, ali ne za sebe. Narod jednog kneza koji će doći razorit će Grad i Svetište: svršetak im je u propasti, a do svršetka rat i određena pustošenja."},{"v":27,"t":"I sklopit će savez s mnogima za jednu sedmicu: a u polovici sedmice prestat će žrtva i prinos: na vrhu Hrama bit će grozota pustoši sve do svršetka, dok se određeno pustošenje ne obori na pustošnika.”"}]},"10":{"hr":[{"v":1,"t":"Treće godine Kira, kralja perzijskoga, Danielu, prozvanome Baltazar, bi objavljena riječ - riječ istinita: velik rat. On je nastojao razumjeti riječ, i razumijevanje bi mu dano u viđenju."},{"v":2,"t":"U te dane ja, Daniel, žalovao sam tri sedmice:"},{"v":3,"t":"nisam jeo tečnih jela; meso ni vino nije ulazilo u moja usta i nisam se mazao uljem dok ne prođoše te tri sedmice."},{"v":4,"t":"Dvadeset i četvrtoga dana prvog mjeseca bijah na obali velike rijeke Tigrisa;"},{"v":5,"t":"podigoh oči da vidim, i gle: Čovjek odjeven u lanene haljine, oko pasa mu pojas od zlata ofirskoga,"},{"v":6,"t":"tijelo mu poput krizolita, lice kao munja, oči kao baklje ognjene, ruke i noge poput mjedi uglađene, zvuk riječi njegovih kao žamor mnoštva."},{"v":7,"t":"Jedini ja, Daniel, gledah ovo viđenje, ljudi koji bijahu sa mnom ne vidješe ga, ali ih spopade silan strah te pobjegoše da se sakriju."},{"v":8,"t":"Ostadoh sam gledajući to veliko viđenje; onemoćah, lice mi problijedje, iznakazi se, snaga me ostavi."},{"v":9,"t":"Začuh glas njegovih riječi, i kad razabrah glas, onesvijestih se i padoh licem na zemlju."},{"v":10,"t":"I gle: ruka me dotače i pomože mi da se uprem na koljena i na dlanove."},{"v":11,"t":"On mi reče: “Daniele, miljeniče, pripazi na riječi koje ću ti kazati! Ustani, jer ja sam evo k tebi poslan.” To reče, a ja ustadoh dršćući."},{"v":12,"t":"I kaza mi: “Ne boj se, Daniele, jer od prvoga dana kad si odlučio da se poniziš pred svojim Bogom da bi razumio, tvoje su riječi uslišane i ja sam došao zbog tvojih riječi."},{"v":13,"t":"Knez kraljevstva perzijskoga protivio mi se dvadeset i jedan dan, ali Mihael, jedan od prvih Knezova, dođe mi u pomoć. Ostavih ga nasuprot Knezu perzijskome,"},{"v":14,"t":"a ja dođoh da ti kažem što će zadesiti tvoj narod na svršetku dana. Jer još će jedno viđenje biti za one dane.”"},{"v":15,"t":"Pošto mi to reče, ja oborih pogled na zemlju, bez riječi."},{"v":16,"t":"I gle: onaj, sličan sinu čovječjem dotače se mojih usana. Otvorih usta da govorim te rekoh onome koji stajaše preda mnom: “Gospodaru moj, zbog ovog viđenja obuzeše me tjeskobe i onemoćah."},{"v":17,"t":"I kako će sluga Gospodina svoga govoriti s Gospodinom kad posve onemoćah i dah me ostavi?”"},{"v":18,"t":"Tada me se opet dotače onaj što bijaše kao čovjek te me okrijepi."},{"v":19,"t":"On reče: “Ne boj se, miljeniče! Mir tebi! Budi jak! Ohrabri se!” I dok mi to govoraše, ja se ohrabrih pa rekoh: “Govori, Gospodine, jer si me ohrabrio!”"},{"v":20,"t":"Tada će on: “Znaš li zašto sam došao k tebi? Sad ću se vratiti da se borim protiv Kneza Perzije; a čim svršim, doći će Knez Grčke."},{"v":21,"t":"Ali ću ti prije otkriti što je zapisano u Knjizi istine. Nema nikoga tko bi se sa mnom protiv njih borio, osim Mihaela, Kneza vašega,"}]},"11":{"hr":[{"v":1,"t":"moje potpore i moga okrilja."},{"v":2,"t":"A sada ću ti otkriti istinu. Evo: još će tri kralja ustati za Perziju: četvrti će biti bogatiji od svih ostalih, pa kad se zbog svoga bogatstva osili, sve će podići protiv kraljevstva grčkoga."},{"v":3,"t":"Ustat će junački kralj, vladat će silnom moću i činiti što ga bude volja."},{"v":4,"t":"A čim se ustane, njegovo će se kraljevstvo raspasti i bit će razdijeljeno na četiri vjetra nebeska, ali ne među njegove potomke; i neće više biti tako moćno kao za njegove vladavine, jer će njegovo kraljevstvo biti razoreno i predano drugima, a ne njima."},{"v":5,"t":"Kralj će Juga postati moćan; jedan će od njegovih zapovjednika biti moćniji od njega i zavladat će većom moću nego što je njegova."},{"v":6,"t":"Nekoliko godina kasnije oni će se udružiti, a kći kralja Juga doći će kralju Sjevera da sklope ugovor. Ali ona tim neće sačuvati snagu svoje mišice i njezino se potomstvo neće održati: bit će predana ona, i njezina pratnja, i njezino dijete, i njezin pomagač u tim vremenima."},{"v":7,"t":"No jedan će se izdanak njezina korijena podići na njezino mjesto, navalit će na vojsku, prodrijet će u tvrđavu kralja Sjevera, postupati s njima po miloj volji i pobijediti ih."},{"v":8,"t":"Pa i njihove bogove, njihove kipove i njihovo dragocjeno suđe, srebrno i zlatno, odnijet će kao plijen u Egipat. Nekoliko godina bit će jači od kralja Sjevera,"},{"v":9,"t":"koji će onda prodrijeti u kraljevstvo kralja Juga, odakle će se vratiti u svoju zemlju."},{"v":10,"t":"Ali će se onda njegovi sinovi naoružati, skupit će silnu vojsku, odlučno će navaliti i poput poplave proći, zatim će se opet zametnuti rat sve do njegove utvrde."},{"v":11,"t":"Tada će se kralj Juga razgnjeviti i zavojštiti na kralja Sjevera; podići će silnu vojsku i nadvladati vojsku njegovu."},{"v":12,"t":"Mnoštvo će biti uništeno, a on će se zbog toga uzoholiti; pobit će desetke tisuća, ali se neće održati:"},{"v":13,"t":"kralj će Sjevera opet dići vojsku veću nego prije, i poslije nekoliko godina navalit će s velikom, dobro opremljenom vojskom."},{"v":14,"t":"U to vrijeme mnogi će se podići protiv kralja Juga; ustat će i nasilnici iz tvog naroda da se ispuni viđenje, ali će propasti."},{"v":15,"t":"Doći će kralj Sjevera: podići će nasipe da zauzme jedan utvrđeni grad. Mišice Juga neće odoljeti, pa ni izabrane čete neće imati snage da se odupru."},{"v":16,"t":"Onaj će navaliti protiv njega i učinit će s njime kako mu se prohtije - nitko mu se neće oprijeti: zaustavit će se u Divoti, uništenje je u njegovim rukama."},{"v":17,"t":"Čvrsto odlučivši da se pošto-poto domogne svega njegova kraljevstva, sklopit će s njim ugovor dajući mu jednu kćer za ženu da ga upropasti, ali mu neće uspjeti, neće se to zbiti."},{"v":18,"t":"Zatim će se okrenuti prema otocima i mnoge će osvojiti, ali će jedan zapovjednik dokrajčiti tu sramotu, sramotu mu sramotom vratiti."},{"v":19,"t":"Brže će nagnuti prema utvrdama svoje zemlje, ali će posrnuti, pasti, više ga neće biti."},{"v":20,"t":"Na njegovo će mjesto doći jedan koji će u diku kraljevstva poslati poreznika, ali će u kratko vrijeme poginuti bez gnjeva i boja."},{"v":21,"t":"Na njegovo će se mjesto uzdići nitkov kome ne pripada kraljevska čast. Ali on će iznenada doći i spletkama se domoći kraljevstva."},{"v":22,"t":"Pred njim će biti preplavljene i skršene navalne snage i sam knez Saveza."},{"v":23,"t":"Unatoč sporazumu s njime, izdajnički će navaliti i svladati ga s malo ljudi."},{"v":24,"t":"Iznenada će upasti u bogate pokrajine i postupat će kako nisu postupali njegovi očevi ni očevi njegovih otaca, rasipajući među svoje plijen, pljačku i bogatstvo, smišljat će osnove protiv tvrdih gradova, ali samo za neko vrijeme."},{"v":25,"t":"Pokrenut će, s velikom vojskom, svoju snagu i hrabrost protiv kralja Juga. Kralj Juga krenut će u rat s mnogom i moćnom vojskom, ali neće izdržati, jer će se protiv njega skovati spletke."},{"v":26,"t":"I oni koji jeđahu za njegovim stolom skršit će ga: njegova će vojska biti uništena i mnogi će posječeni popadati."},{"v":27,"t":"Oba će kralja smišljati zlo; sjedeći za istim stolom, govorit će laži jedan drugome: ali neće uspjeti, jer je svršetak odložen do određenog vremena."},{"v":28,"t":"Vratit će se on u svoju zemlju s velikim blagom; srcem protiv svetoga Saveza, učinit će svoje i vratiti se u svoju zemlju."},{"v":29,"t":"U određeno vrijeme opet će krenuti protiv Juga, ali sada neće biti kao prvi put."},{"v":30,"t":"Kitimski će brodovi navaliti na njega, i on će se uplašiti. Vratit će se, bjesnjeti protiv svetoga Saveza i opet će se sporazumjeti s onima koji napustiše sveti Savez."},{"v":31,"t":"Čete će njegove doći i oskvrnuti svetište-tvrđu, dokinut' svagdašnju žrtvu i ondje postaviti grozotu pustoši."},{"v":32,"t":"Svojim će spletkama navesti na otpad one koji se ogrešuju o Savez, ali ljudi koji ljube Boga ostat će postojani i vršit će svoje."},{"v":33,"t":"Umnici u narodu poučavat će mnoštvo, ali će ih jedno vrijeme zatirati mačem i ognjem, izgnanstvom i pljačkanjem."},{"v":34,"t":"Dok ih budu zatirali, samo će im nekolicina pomagati, a mnogi će im se pridružiti prijevarno."},{"v":35,"t":"Od umnika neki će pasti, da se prokušaju, probrani, čisti do vremena svršetka, jer još nije došlo određeno vrijeme."},{"v":36,"t":"Kralj će raditi što god mu se prohtije, uznoseći i uzdižući sebe iznad svih bogova: protiv Boga nad bogovima govorit će hule i uspijevat će dok se gnjev ne navrši - jer ono što je određeno, to će se ispuniti."},{"v":37,"t":"Neće mariti za bogove svojih otaca ni za Miljenika ženÄa niti za kojega drugog boga: samog će sebe izdizati iznad sviju."},{"v":38,"t":"Mjesto njih častit će boga tvrđava, boga koga nisu poznavali njegovi očevi, častiti ga zlatom i srebrom, dragim kamenjem i drugim dragocjenostima."},{"v":39,"t":"Navalit će na tvrđave gradova pomoću stranog boga: one koji njega priznaju obasut će počastima i dat će im vlast nad mnoštvom i dijelit će im zemlju za nagradu."},{"v":40,"t":"U vrijeme svršetka kralj će se Juga zaratiti s njime; kralj će Sjevera navaliti na nj svojim kolima, svojim konjanicima i svojim mnogim brodovima. Provalit će u zemlje i proći njima poput poplave."},{"v":41,"t":"Prodrijet će u Divotu i mnogi će pasti. Njegovim će rukama izmaći Edom i Moab i glavnina sinova Amonovih."},{"v":42,"t":"Pružit će svoju ruku za zemljama: Egipat mu neće izmaći."},{"v":43,"t":"On će se domoći zlatnog i srebrnog blaga i svih dragocjenosti Egipta. Pratit će ga Libijci i Etiopljani."},{"v":44,"t":"Ali će ga uznemiriti vijesti s istoka i sa sjevera te će poći vrlo gnjevan da uništi i zatre mnoštvo."},{"v":45,"t":"Postavit će svoje dvorske šatore između mora i Svete gore Divote. Ali će i njemu doći kraj, i nitko mu neće pomoći."}]},"12":{"hr":[{"v":1,"t":"U ono će vrijeme ustati Mihael, veliki knez koji štiti sinove tvog naroda. Bit će to vrijeme tjeskobe kakve ne bijaše otkako je ljudi pa do toga vremena. U ono vrijeme tvoj će se narod spasiti - svi koji se nađu zapisani u Knjizi."},{"v":2,"t":"Tada će se probuditi mnogi koji snivaju u prahu zemljinu; jedni za vječni život, drugi za sramotu, za vječnu gadost."},{"v":3,"t":"Umnici će blistati kao sjajni nebeski svod, i koji su mnoge učili pravednosti, kao zvijezde navijeke, u svu vječnost."},{"v":4,"t":"A ti, Daniele, drži u tajnosti ove riječi i zapečati ovu knjigu do vremena svršetka! Mnogi će tumarati, i bezakonja će rasti.”"},{"v":5,"t":"Ja, Daniel, pogledah, kad eno: druga dvojica stajahu jedan s jedne, drugi s druge strane rijeke."},{"v":6,"t":"Jedan upita čovjeka odjevena u lanene haljine koji stajaše iznad voda rijeke: “Kada će doći kraj tim čudesima?”"},{"v":7,"t":"Začuh čovjeka odjevena u lanene haljine, koji stajaše iznad voda rijeke; on podiže k nebu desnicu i ljevicu, kunući se Vječno živim. “Nakon jednog vremena, dva vremena i pola vremena - kada dođe kraj rasulu snage svetoga naroda - sve će se to svršiti.”"},{"v":8,"t":"Ja slušah, ali ne razumjeh, pa upitah: “Gospodaru, kako će to svršiti?”"},{"v":9,"t":"On reče: “Idi, Daniele, ove su riječi tajne i zapečaćene do vremena svršetka."},{"v":10,"t":"Mnogi će se očistiti, ubijeliti i prokušati; a bezbožnici će i dalje biti bezbožni; bezbožnici se neće urazumjeti, a umnici će razumjeti."},{"v":11,"t":"Od časa kad bude dokinuta svagdašnja žrtva i postavljena grozota pustoši: tisuću dvjesta i devedeset dana."},{"v":12,"t":"Blago onomu koji dočeka i dosegne tisuću trista trideset i pet dana!"},{"v":13,"t":"A ti idi i otpočini; ustat ćeš da primiš svoju baštinu na kraju dana.”"}]}},"HOS":{"1":{"hr":[{"v":1,"t":"Riječ Jahvina koja dođe Hošei, sinu Beerijevu, u dane Uzije, Jotama, Ahaza i Ezekije, kraljeva judejskih, u dane Jeroboama, sina Joaševa, kralja izraelskog."},{"v":2,"t":"Početak riječi Jahvinih Hošei. Jahve reče Hošei: “Idi, oženi se bludnicom i izrodi djecu bludničku, jer se zemlja bludu odala, odmetnuvši se od Jahve!”"},{"v":3,"t":"I on ode, uze Gomeru, kćer Diblajimovu, koja zače i rodi mu sina."},{"v":4,"t":"Jahve mu reče: “Nadjeni mu ime Jizreel, jer još samo malo i kaznit ću pokolje jizreelske na domu Jehuovu i dokončat ću kraljevstvo doma Izraelova."},{"v":5,"t":"I u taj dan slomit ću luk Izraelov u Dolini jizreelskoj.”"},{"v":6,"t":"I ona opet zače i rodi kćer. I reče mu Jahve: “Nadjeni joj ime Nemila, jer mi odsad neće biti mila kuća Izraelova, od nje ću se povući;"},{"v":7,"t":"a omiljet će mi kuća Judina, spasit ću je Jahvom, Bogom njihovim, a neću je spasiti lukom, mačem ni kopljem, ni konjima ni konjanicima.”"},{"v":8,"t":"Kad odoji Nemilu, zače opet i rodi sina."},{"v":9,"t":"I reče Jahve: “Nadjeni mu ime Ne-narod-moj, jer više niste narod moj i ja vama nisam više Onaj koji jest.”"}]},"2":{"hr":[{"v":1,"t":"“A djece Izraelove bit će brojem k'o pijeska u moru što se izmjerit' ne može ni izbrojit'. Umjesto da im govore: 'Vi niste moj narod,' zvat će ih: 'Sinovi Boga živoga.'"},{"v":2,"t":"Ujedinit će se sinovi Judini i sinovi Izraelovi, postavit će sebi jednoga glavara i otići će iz zemlje; jer velik će biti dan jizreelski."},{"v":3,"t":"Recite braći svojoj: 'Narode moj,' sestrama svojim: 'Mila.'"},{"v":4,"t":"Podignite tužbu, podignite, protiv majke svoje, jer ona mi nije više žena, a ja joj muž više nisam. Nek' odbaci od sebe bludničenja i preljube izmeđ' svojih dojki,"},{"v":5,"t":"da je golu ne svučem te učinim da bude k'o na dan rođenja; da je ne obratim u pustinju, da je u zemlju suhu ne obratim i žeđu ne umorim."},{"v":6,"t":"Ja joj djece neću milovati, jer djeca su to bludnička."},{"v":7,"t":"Da, bludu se odala mati njihova, sramotila se ona koja ih zače. Da, rekla je: 'Trčat ću za svojim milosnicima, za njima koji mi daju kruh moj i vodu, vunu moju i lan, ulje i piće moje.'"},{"v":8,"t":"Stoga ću put joj trnjem zagraditi, zidom opkoliti, da ne nađe više svojih staza."},{"v":9,"t":"I trčat će za milosnicima, ali ih stići neće, tražit će ih, al' ih neće pronaći. Tada će reći: 'Idem se vratiti prvome mužu, jer sretnija bijah prije nego sada.'"},{"v":10,"t":"I ona nije razumjela da joj ja davah i žito i mošt i ulje, da je ja obasipah srebrom i zlatom od kojega načiniše baale."},{"v":11,"t":"Stoga ću uzeti natrag svoje žito u svoje vrijeme i svoj mošt u pravi čas; oduzet ću svoju vunu i svoj lan kojima je imala pokriti golotinju svoju;"},{"v":12,"t":"sad ću joj otkriti sramotu na oči njenih milosnika, i nitko je iz moje neće izbaviti ruke."},{"v":13,"t":"Učinit ću kraj svim njenim veseljima, svetkovinama, mlađacima, subotama i svim blagdanima njezinim."},{"v":14,"t":"Opustošit ću joj čokote i smokve za koje je govorila: 'To je plaća što mi je dadoše moji milosnici.' Obratit ću ih u šikarje, i životinje će ih poljske obrstiti."},{"v":15,"t":"Kaznit ću je za dane Baalove kojima je kad palila, kitila se grivnom i kolajnom i trčala za svojim milosnicima; a mene je zaboravljala - riječ je Jahvina."},{"v":16,"t":"Stoga ću je, evo, primamiti, odvesti je u pustinju i njenu progovorit' srcu."},{"v":17,"t":"I vratit ću joj ondje njene vinograde, i od Doline ću akorske učiniti vrata nade. Ondje će mi odgovarat' ona kao u dane svoje mladosti, kao u vrijeme kada je izišla iz Egipta."},{"v":18,"t":"U onaj dan - riječ je Jahvina - ti ćeš me zvati: 'Mužu moj', a nećeš me više zvati: 'Moj Baale.'"},{"v":19,"t":"Uklonit ću joj iz usta imena baalska i neće im više ime spominjati."},{"v":20,"t":"U onaj dan, učinit ću za njih savez sa životinjama u polju, sa pticama nebeskim i gmazovima zemskim; luk, mač i boj istrijebit ću iz zemlje da mirno u njoj počiva."},{"v":21,"t":"Zaručit ću te sebi dovijeka; zaručit ću te u pravdi i u pravu, u nježnosti i u ljubavi;"},{"v":22,"t":"zaručit ću te sebi u vjernosti i ti ćeš spoznati Jahvu."},{"v":23,"t":"U onaj dan - riječ je Jahvina - odazvat ću se nebesima, a ona će se zemlji odazvati;"},{"v":24,"t":"zemlja će se odazvati žitu, moštu i ulju, a oni će se odazvati Jizreelu."},{"v":25,"t":"I posijat ću ga u zemlji, zamilovat ću Nemilu, Ne-narodu mom reći ću: 'Ti si narod moj!' a on će reći: 'Bože moj!'”"}]},"3":{"hr":[{"v":1,"t":"Potom mi Jahve reče: “Idi opet, ljubi ženu koja drugog ljubi i čini preljub, kao što Jahve ljubi djecu Izraelovu dok se oni k drugim bogovima okreću i žude za kolačima od grožđa.”"},{"v":2,"t":"Ja je tad kupih za petnaest srebrnika, za homer i letek ječma,"},{"v":3,"t":"i rekoh joj: “Za mnogo dana ostat ćeš mi povučena, nećeš se odavati bludu ni podavati nikojem čovjeku, a ni ja neću k tebi prilaziti.”"},{"v":4,"t":"Jer mnogo će dana sinovi Izraelovi ostati bez kralja i bez kneza, bez žrtve i bez stupa, bez oplećka i bez kumira."},{"v":5,"t":"Poslije toga, sinovi će se Izraelovi vratiti; tražit će Jahvu, Boga svoga, i Davida, svoga kralja; sa strahom će pristupiti k Jahvi i k njegovim dobrima, na kraju dana."}]},"4":{"hr":[{"v":1,"t":"Čujte riječ Jahvinu, sinovi Izraelovi, jer Jahve se parbi sa stanovnicima zemlje."},{"v":2,"t":"Nema više vjernosti, nema ljubavi, nema znanja Božjega u zemlji, već proklinjanje i laž, ubijanje i krađa, preljub i nasilje, jedna krv drugu stiže."},{"v":3,"t":"Stoga tuguje zemlja i ginu svi stanovnici s poljskim zvijerima i pticama nebeskim te ugibaju i ribe u moru."},{"v":4,"t":"Ipak neka se nitko ne parbi, neka nitko ne kori! Ali s tobom se moram parbiti, svećeniče."},{"v":5,"t":"Danju ti posrćeš, a noću s tobom posrće i prorok; pogubit ću mater tvoju."},{"v":6,"t":"Moj narod gine: nema znanja; jer si ti znanje odbacio, i ja odbacujem tebe iz svećenstva svoga; jer si Zakon svoga Boga zaboravio, i ja ću tvoje zaboraviti sinove."},{"v":7,"t":"Što ih je više bivalo, više su protiv mene griješili, Slavu su svoju Sramotom zamijenili."},{"v":8,"t":"Grijesima mog naroda oni se hrane, duša im hlepi za bezakonjem njegovim."},{"v":9,"t":"I sa svećenikom bit će k'o i s narodom; kaznit ću ga za njegove putove i naplatit ću mu za njegova djela."},{"v":10,"t":"Jest će, ali se nasititi neće; bludničit će, ali se neće množiti, jer oni su prestali štovati Jahvu -"},{"v":11,"t":"blud, mošt i vino zarobiše im srce."},{"v":12,"t":"Narod moj savjet traži od drva, palica mu njegova daje odgovore: jer duh razvratni njih zavodi te se od Boga svoga bludu odaju."},{"v":13,"t":"Oni žrtvuju na gorskim vrhuncima i na bregovima pale kad, pod hrastom, jablanom i dubom; jer je tako lagodno pod njihovom sjenom. I zato, odaju li se vaše kćeri bludu, čine li preljub vaše nevjeste,"},{"v":14,"t":"neću vam kazniti kćeri što bludniče niti nevjeste vaše što preljub čine; jer oni sami idu nasamo s bludnicama i žrtvuju s milosnicama hramskim. Tako, bez razuma narod u propast srlja!"},{"v":15,"t":"Ako li se ti bludu odaješ, Izraele, neka bar Juda ne griješi! I ne idite u Gilgal, ne penjite se u Bet Aven, ne kunite se “živoga mi Jahve.”"},{"v":16,"t":"Jer poput junice tvrdoglave Izrael tvrdoglav postade, pa kako da ga Jahve sad pase k'o janje na prostranoj livadi?"},{"v":17,"t":"Efrajim se udružio s kumirima: pusti ga!"},{"v":18,"t":"A kad završe pijanku, bluda se prihvaćaju, Sramotu vole više nego Slavu svoju."},{"v":19,"t":"Vihor će ih svojim krilima stegnuti i njihovi će ih osramotit' žrtvenici."}]},"5":{"hr":[{"v":1,"t":"Poslušajte ovo, svećenici, pazi, dome Izraelov, dome kraljev, de posluhni, jer vaš je sud! Vi ste bili zamka u Mispi i mreža napeta na Taboru."},{"v":2,"t":"Jamu su duboko iskopali prestupnici, ali ću ih sve kazniti."},{"v":3,"t":"Poznajem ja Efrajima, Izrael mi nije sakriven: da, Efrajime, bludu si se odao, okaljao si se, Izraele."},{"v":4,"t":"Ne daju im djela njihova da se Bogu svome vrate, jer je duh bluda među njima; oni Jahve ne poznaju."},{"v":5,"t":"Ponos Izraelov svjedoči protiv njega; svojom krivnjom posrnu Efrajim, posrnut će i Juda s njim."},{"v":6,"t":"Ići će s ovcama i govedima Jahvu tražiti ali ga naći neće - povukao se od njih!"},{"v":7,"t":"Jahvu su iznevjerili: rodili su kopilad; vjetar će žarki proždrijeti polja njihova."},{"v":8,"t":"Zasvirajte u rog u Gibeji, u trublju u Rami, uzbunite Bet Aven: za petama su ti, Benjamine!"},{"v":9,"t":"Opustošit će Efrajima u dan kazne: među plemenima Izraelovim objavljujem ono što je sasvim pouzdano."},{"v":10,"t":"Knezovi judejski postadoše poput onih što razmiču međe; na njih ću k'o vodu gnjev svoj izliti."},{"v":11,"t":"Efrajim je tlačitelj, on pravdu gazi jer mu se svidjelo ići za ništavilom."},{"v":12,"t":"A ja ću biti poput moljca Efrajimu, kao gnjilež kući Judinoj."},{"v":13,"t":"Tad je Efrajim svoju bolest vidio, a Juda ranu svoju; i pođe Efrajim u Asiriju, obrati se Juda velikome kralju; al' on vas neće iscijeliti niti vam ranu vašu zaliječiti."},{"v":14,"t":"Jer k'o lav ću biti Efrajimu, kao lavić domu Judinu; ja, ja ću razderati i otići, odnijet ću i nitko neće spasiti."},{"v":15,"t":"Poći ću, vratit ću se na svoje mjesto, dok krivnju ne priznaju i lice moje ne potraže; kad u nevolji budu, iskat će me."}]},"6":{"hr":[{"v":1,"t":"“Hajde, vratimo se Jahvi! On je razderao, on će nas iscijeliti: on je udario, on će nam poviti rane;"},{"v":2,"t":"poslije dva dana oživit će nas, trećeg će nas dana podignuti i mi ćemo živjeti pred njim."},{"v":3,"t":"Težimo da upoznamo Jahvu: k'o zora pouzdan mu dolazak. On će nam doći poput dažda jesenskog, poput kiše proljetne što natapa zemlju.”"},{"v":4,"t":"Što za tebe mogu učiniti, Efrajime? Što za tebe mogu učiniti, Judo? K'o oblak jutarnji ljubav je vaša, k'o rana rosa koje nestaje."},{"v":5,"t":"Zato sam ih preko proroka sjekao i ubijao riječima usta svojih; al' sud će tvoj izaći k'o svjetlost."},{"v":6,"t":"Jer ljubav mi je mila, ne žrtve, poznavanje Boga, ne paljenice."},{"v":7,"t":"Al' oni su kod Adama prekršili Savez i ondje mene iznevjerili."},{"v":8,"t":"Gilead je grad zlikovački, pun krvavih tragova."},{"v":9,"t":"Družba je svećenička kao zasjeda razbojnička: ubijaju na šekemskom putu; odista, sramotu počinjaju!"},{"v":10,"t":"Strahotu vidjeh u domu Izraelovu; Efrajim se ondje bludu odaje i skvrni se Izrael."},{"v":11,"t":"I tebi sam, Judo, žetvu odredio kad okrenem udes naroda svoga."}]},"7":{"hr":[{"v":1,"t":"Kad hoću Izraela liječiti, otkriva se bezakonje Efrajimovo i zloća Samarije; prijevarom se bave oni: tat u kuću provaljuje, a vani napadaju razbojnici."},{"v":2,"t":"I u srcu svome oni ne kažu da ja pamtim svu zlopakost njihovu! Ali djela su ih njihova sad opkolila, pred licem mojim ona stoje."},{"v":3,"t":"Svojom zloćom razveseljuju kralja, a knezove podlošću svojom."},{"v":4,"t":"Svi su oni preljubnici, kao peć su ražarena koju pekar više ne potpaljuje kad zamijesi tijesto pa dok ne ukisne."},{"v":5,"t":"U dan kralja našega knezovi obolješe od žestine vina, a on ruku pruža pijanima."},{"v":6,"t":"U zavjeri srce im se žari poput peći; svu noć njihova jarost drijema, ujutru se razgara k'o plam ognjeni;"},{"v":7,"t":"poput peći svi se raspalili te proždiru svoje suce. Padoše svi njihovi kraljevi, a nijedan od njih zazvao me nije."},{"v":8,"t":"Efrajim se miješa s narodima, Efrajim je pogača što je ne prevrnuše."},{"v":9,"t":"Tuđinci proždiru snagu njegovu, a on toga i ne zna! Sjedine mu pobijeliše glavu, a on toga i ne zna!"},{"v":10,"t":"Naprasitost Izraelova protiv njih samih svjedoči; i oni se ne vraćaju Jahvi, Bogu svome, i uza sve to oni ga ne traže!"},{"v":11,"t":"Efrajim je kao golubica plaha i bez razuma; oni pozivaju Egipat, idu u Asiriju."},{"v":12,"t":"Kamo god otišli, na njih ću razapeti svoju mrežu, oborit ću ih kao ptice nebeske, za njihovu ih kazniti zloću."},{"v":13,"t":"Teško njima jer od mene odbjegoše! Propast na njih jer se pobuniše protiv mene! Otkupit' ih hoću, a oni protiv mene lažu."},{"v":14,"t":"Oni me ne prizivlju iz srca kada kukaju na svojim ležajima; razdiru svoje lice zbog žita i mošta, ali protiv mene se bune."},{"v":15,"t":"Dok sam im ja mišicu krijepio, oni su zlosti smišljali protiv mene!"},{"v":16,"t":"Okreću se prema ništavostima, oni su poput varljiva luka. Poradi razbješnjela jezika knezovi će im od mača pasti, bit će im to na ruglo u zemlji egipatskoj!"}]},"8":{"hr":[{"v":1,"t":"Trublju na usta, poput stražara na Domu Jahvinu; jer oni moj Savez prestupiše, otpadoše od moga Zakona."},{"v":2,"t":"Meni viču: “Poznajemo te, Bože Izraelov.”"},{"v":3,"t":"Ali je Izrael odbacio dobro, dušman će ga progoniti."},{"v":4,"t":"Kraljeve su postavljali bez mene, knezove birali bez znanja moga. Od srebra svog i zlata načiniše sebi kumire da budu uništeni."},{"v":5,"t":"Odbacih tvoje tele, Samarijo, na njih se gnjev moj rasplamtio. Dokle će ostati nečisti sinovi Izraelovi?"},{"v":6,"t":"Umjetnik ga je neki načinio, i ono Bog nije. Prometnut će se u komadiće tele samarijsko."},{"v":7,"t":"Posijali su vjetar, i požet će oluju; žito im neće proklijati, neće brašna dati; ako ga i dade proždrijet će ga tuđinci."},{"v":8,"t":"Progutan je Izrael, evo ga među narodima poput nevrijedne posude;"},{"v":9,"t":"jer otiđoše k Asircu, divljem magarcu što sam živi! Efrajim obdaruje milosnike."},{"v":10,"t":"Neka ih samo obdaruje, među narode ću ih sada razasuti: i doskora će uzdrhtati pod teretom kralja knezova."},{"v":11,"t":"Žrtvenike je umnožio Efrajim, za grijeh su mu oni poslužili."},{"v":12,"t":"Da mu i tisuću zakona svojih napišem, oni ih smatraju tuđima."},{"v":13,"t":"Nek' žrtvuju klanice što mi ih prinose, nek' samo jedu meso! Jahvi se ne mile. Odsad će se spominjati bezakonja njihova i njihove će kazniti grijehe: u Egipat će se oni vratiti."},{"v":14,"t":"Izrael je zaboravio tvorca svoga i sebi dvorove sagradio; Juda je namnožio gradove tvrde. Oganj ću pustiti na gradove njegove; vatra će mu dvorove progutati."}]},"9":{"hr":[{"v":1,"t":"Ne raduj se, Izraele, ne kliči k'o drugi narodi; bludu se oda, jer, ostavivši Boga svoga, zavolio si plaću bludničku po svim gumnima žitnim."},{"v":2,"t":"Ni gumno ni kaca neće ih hraniti, i mlado će ih vino prevariti."},{"v":3,"t":"Neće više živjeti u zemlji Jahvinoj, Efrajim će se vratiti u Egipat i nečista će jela jesti u Asuru."},{"v":4,"t":"Neće više Jahvi lijevati vina, nit' će mu prinositi žrtve svoje; kruh će im biti kao kruh žalosti, i nečist će biti tko ga bude jeo; jer njihov je kruh samo za njih, neće ući u Dom Jahvin."},{"v":5,"t":"Što ćete činiti na dan blagdanski, na dan svetkovine Jahvine?"},{"v":6,"t":"Jer, evo gdje odoše pred pustošenjem; prihvatit će ih Egipat, sahraniti Memfis, srebrna im blaga kopriva će baštiniti, šatore će njihove obrasti trnje."},{"v":7,"t":"Dođoše dani kazne! Dođoše dani odmazde! Nek' znade Izrael! Lud je prorok, nadahnuti bunca! Zbog velikog bezakonja tvoga i silnog buntovništva."},{"v":8,"t":"Efrajim uhodi šator prorokov, stavljaju mu zamke po svim putovima, odmazda je u kući Boga njegova."},{"v":9,"t":"U duboku su pali pokvarenost kao u dane Gibeje; spomenut će se Jahve bezakonja njihova i grijehe će njihove kazniti."},{"v":10,"t":"Kao grožđe u pustinji nađoh ja Izraela, kao rani plod na smokvi vidjeh oce vaše; oni dođoše u Baal Peor, posvetiše se sramoti i postadoše grozote kao ljubimci njihovi."},{"v":11,"t":"Odletje poput ptice slava Efrajimova: od rođenja, od utrobe, od začeća."},{"v":12,"t":"Ako i podignu svoje sinove, oduzet ću ih prije dobi muževne, da, teško njima kada ih ostavim!"},{"v":13,"t":"Efrajim je k'o da gledam Tir na njivi posađen, al' će Efrajim djecu svoju voditi na klanje."},{"v":14,"t":"Daj im, o Jahve! A što da im dadeš? Daj im krilo jalovo, dojke usahle."},{"v":15,"t":"U Gilgalu sva je njihova zloća, ondje sam ih zamrzio. Zbog njihovih djela opakih iz kuće svoje ću ih izagnati, voljeti ih više neću, svi su im knezovi odmetnici."},{"v":16,"t":"Pogođen je Efrajim, korijen mu je usahnuo; roda neće imati. Ako im se i rodi djece, ubit ću im mili plod utrobe."},{"v":17,"t":"Odbacit će ih Bog moj jer ga nisu poslušali; i potucat će se među narodima."}]},"10":{"hr":[{"v":1,"t":"Bujna je loza bio Izrael, rod bogat ona je nosila. I što mu je više rodilo plodova, to je više umnažao žrtvenike; što mu je bogatija zemlja bila, to je kićenije dizao stupove."},{"v":2,"t":"Srce je njihovo prijevarno, okajat će to oni! Porušit će im On žrtvenike, polomiti stupove njihove."},{"v":3,"t":"Kazat će tada: “Mi kralja nemamo jer se Jahve bojali nismo. TÓa čemu bi nam bio kralj?”"},{"v":4,"t":"Riječi prosiplju, lažno se kunu, sklapaju saveze; a pravo cvate k'o otrovno bilje u brazdama polja."},{"v":5,"t":"Za tele betavensko strepe stanovnici Samarije; da, zbog njega tuguje narod njegov, svećenici njegovi kukaju nad njim, nad slavom njegovom jer je od njega prognana."},{"v":6,"t":"A njega samog odvući će u Asiriju na dar velikome kralju. Efrajima stid će spopasti, crvenjet će se Izrael zbog svoje odluke."},{"v":7,"t":"Uništena je Samarija. Njen kralj tek trunak je vodi na površju."},{"v":8,"t":"Bit će razorene sramne uzvišice, grijeh Izraelov; trnje će i čičak rasti po žrtvenicima njihovim. Tad će govoriti brdima: “Pokrijte nas!” i bregovima: “Padnite na nas!”"},{"v":9,"t":"Većma no u dane gibejske griješio si, Izraele! A da se i ondje zaustaviše, ne bi li ih zatekao rat kao bezakonike gibejske?"},{"v":10,"t":"Kako mi se svidi, kaznit ću ih: sabrat će se protiv njih narodi da ih za dvostruko kazne bezakonje."},{"v":11,"t":"Efrajim je junica dobro naučena koja rado vrše; šiju ću joj lijepu ujarmiti, upregnut ću Efrajima. Juda će orati, Jakov branat'."},{"v":12,"t":"Sijte pravednost, požet ćete ljubav; krčite zemlje nove: vrijeme je da Jahvu tražite dok ne dođe i podaždi vam pravdom."},{"v":13,"t":"Orali ste bezbožnost, želi bezakonje, jeli plod prijevare. Pouzdao si se u kola svoja i u mnoštvo svojih ratnika,"},{"v":14,"t":"zato će se vika bojna razlijegati tvojim gradovima i sve će ti tvrđe biti razorene k'o što Šalman razori Bet Arbel u dan ratni, kada mater smrskaše na sinovima."},{"v":15,"t":"Evo što vam Betel učini jer ste u zlu ogrezli: u zoru će zavijek nestati kralja Izraelova!"}]},"11":{"hr":[{"v":1,"t":"Dok Izrael bijaše dijete, ja ga ljubljah, iz Egipta dozvah sina svoga."},{"v":2,"t":"Al' što sam ih više zvao, sve su dalje od mene odlazili; baalima su žrtvovali, kadili kumirima."},{"v":3,"t":"A ja sam Efrajima hodati učio, držeći ga za ruke njegove; al' oni ne spoznaše da sam se za njih brinuo."},{"v":4,"t":"Užima za ljude privlačio sam ih, konopcima ljubavi; bijah im k'o onaj koji u čeljustima njihovim žvale opušta; nad njega se saginjah i davah mu jesti."},{"v":5,"t":"U zemlju egipatsku on će se vratiti, Asirac će mu kraljem biti, jer se ne htjede vratiti k meni."},{"v":6,"t":"Mač će bješnjeti njegovim gradovima, uništiti prijevornice njegove, proždirat će zbog spletaka njegovih."},{"v":7,"t":"Narod je moj sklon otpadu; i premda ga k Višnjem dozivlju, nitko da ga podigne."},{"v":8,"t":"Kako da te dadem, Efrajime, kako da te predam, Izraele! Kako da te dadem kao Admu, da učinim s tobom kao Sebojimu? Srce mi je uznemireno, uzavrela mi sva utroba:"},{"v":9,"t":"neću više gnjevu dati maha, neću opet zatirati Efrajima, jer ja sam Bog, a ne čovjek: Svetac posred tebe - neću više gnjevan dolaziti!"},{"v":10,"t":"Za Jahvom će ići on, k'o lav on će rikati; a kad zarikao bude, sinovi će mu veselo dohrliti sa zapada;"},{"v":11,"t":"k'o ptice će dohrliti iz Egipta, k'o golubica iz zemlje asirske, i naselit ću ih po kućama njihovim - riječ je Jahvina."}]},"12":{"hr":[{"v":1,"t":"Opkolio me lažju Efrajim i prijevarom Izraelov dom. A i Juda još je nestalan Bogu, Svecu vjernome."},{"v":2,"t":"Efrajim pase vjetar, za vjetrom istočnim trči cio dan, sve više je laži njegovih i nasilja. Savez sklapaju s Asirijom, ulje nose u Egipat."},{"v":3,"t":"S Izraelom ima Jahve parnicu, kaznit će Jakova prema postupcima, vratit će mu po djelima njegovim."},{"v":4,"t":"Već u krilu materinu brata je potisnuo, u snazi muževnoj s Bogom se borio."},{"v":5,"t":"S Anđelom se borio i nadvladao ga, plakao je i zaklinjao ga. Našao ga je u Betelu i ondje mu je govorio."},{"v":6,"t":"Da, Jahve, Bog nad Vojskama, Jahve je ime njegovo."},{"v":7,"t":"Ti se dakle Bogu svojem vrati, čuvaj ljubav i pravednost i u Boga se svoga uzdaj svagda!"},{"v":8,"t":"U ruci je Kanaanu kriva tezulja, on voli zakidati."},{"v":9,"t":"I reče Efrajim: “Samo sam se obogatio, blago sam nagomilao.” Ali ništa mu od sveg dobitka neće ostati, jer se ogriješio bezakonjima."},{"v":10,"t":"Ja sam Jahve, Bog tvoj, sve od zemlje egipatske, još ću ti dati da stanuješ pod šatorima kao u dane Sastanka;"},{"v":11,"t":"govorit ću prorocima, umnožit ću viđenja i po prorocima prispodobom učiti."},{"v":12,"t":"Gilead je puko bezakonje, ispraznost sama; u Gilgali žrtvuju bikove; zato će im oltari biti k'o hrpe kamenja u brazdama poljskim."},{"v":13,"t":"Jakov pobježe u kraj aramski, za ženu služaše Izrael, za ženu jednu stada čuvaše."},{"v":14,"t":"Al' po Proroku izvede Jahve Izraela iz Egipta, i po Proroku on ga je čuvao."},{"v":15,"t":"Pregorko ga Efrajim uvrijedi: stoga će krv njegovu na nj svaliti, platit će mu Gospod njegov za pogrde."}]},"13":{"hr":[{"v":1,"t":"Kad je Efrajim govorio, strah je zadavao, jer bijaše on prvak u Izraelu, al' ogriješi se Baalom i poginu."},{"v":2,"t":"I sad još griješe oni od srebra praveć' sebi kipove, kumire po svojoj mašti; svi su oni djelo rukotvorca! Tima - vele - žrtvujte, ljudi neka cjelivaju teoce!"},{"v":3,"t":"Zato, bit će oni kao oblak jutarnji, kao rosa koje brzo nestaje, kao pljeva raznesena s gumna, kao dim što kroz otvor izlazi."},{"v":4,"t":"A ja sam Jahve, Bog tvoj sve od zemlje egipatske: drugog Boga osim mene ne ljubi! Osim mene nema spasitelja."},{"v":5,"t":"Ja te ljubljah u pustinji, u zemlji suhoj."},{"v":6,"t":"Ja ih pasoh, i siti bijahu; nasićenima srce se uzoholi; i tako me zaboraviše."},{"v":7,"t":"Stoga ću im biti kao lav, kao leopard što na putu vreba;"},{"v":8,"t":"kao medvjedica kojoj ugrabiše mlade, ja ću se na njih baciti, rastrgat' im grudi do srca; k'o lav ću proždrijeti meso njihovo, zvijeri će ih poljske rastrgati."},{"v":9,"t":"Uništit ću te, Izraele, i tko će ti pomoći?"},{"v":10,"t":"TÓa gdje ti je kralj da te spasi, gdje tvoji knezovi da te brane - oni za koje si govorio: “Daj mi kralja i knezove!”"},{"v":11,"t":"U gnjevu svom kralja ti dadoh i u srdžbi ti ga uzimam."},{"v":12,"t":"Dobro se čuva bezakonje Efrajimovo, grijeh je njegov dobro pohranjen."},{"v":13,"t":"Dođoše na nj trudovi porodiljski, ali on je ludo čedo, ne izlazi na vrijeme iz utrobe materine!"},{"v":14,"t":"Ja ću ih izbaviti od vlasti Podzemlja, od smrti ću ih spasiti! Gdje je tvoja kuga, o smrti, gdje pomor tvoj, Podzemlje! Samilost se sakri od mojih očiju!"},{"v":15,"t":"Tako je rodan među braćom Efrajim, ali će doći vjetar istočni, vjetar Jahvin iz pustinje: isušit će mu izvore, presahnuti studence, opljačkat mu riznicu, blago odnijeti."}]},"14":{"hr":[{"v":1,"t":"Ispaštat će Samarija jer se protiv Boga svoga pobunila. Od mača past će oni, djecu će njihovu smrskati, žene trudne rasporiti."},{"v":2,"t":"Vrati se, Izraele, Jahvi Bogu svome, jer zbog svojeg si bezakonja posrnuo."},{"v":3,"t":"Uzmite sa sobom riječi i Jahvi se vratite. Recite mu: “Skini sa nas bezakonje i dobrohotno primi da ti prinesemo plod svojih usana."},{"v":4,"t":"Asirac nas neće izbavljati i nećemo konje više jahati niti ćemo djelu ruku svojih govoriti: 'Bože naš!' - jer u tebe sirota milost nalazi.”"},{"v":5,"t":"Iscijelit ću ih od njihova otpada, od svega ću ih srca ljubiti; jer gnjev se moj odvratio od njih."},{"v":6,"t":"Bit ću kao rosa Izraelu; kao ljiljan on će cvasti, pustit će korijen poput jablana,"},{"v":7,"t":"nadaleko pružat će izdanke. Ljepota će mu biti kao u masline, miris poput libanonskog."},{"v":8,"t":"Opet će u mojoj sjeni boraviti, uzgajat će svoju pšenicu, vinograde gajit' što će steći ime vina helbonskog."},{"v":9,"t":"Efrajime, što ti imaš još s kumirima? Ja sam ga uslišao i pogledao. Ja sam poput zelena čempresa: po meni si rodan plodovima."},{"v":10,"t":"Tko je mudar neka shvati ovo, i čovjek razuman neka spozna! Jer pravi su putovi Jahvini: pravednici hode po njima, grešnici na njima posrću."}]}},"JOL":{"1":{"hr":[{"v":1,"t":"Riječ Jahvina koja dođe Joelu, sinu Petuelovu."},{"v":2,"t":"Čujte ovo, starci, počujte, svi žitelji zemlje! Je li ovakvo što ikad bilo u vaše dane il' u dane vaših otaca?"},{"v":3,"t":"Recite ovo svojim sinovima, vaši sinovi svojim sinovima, a njihovi sinovi potonjem koljenu."},{"v":4,"t":"Što ostavi šaška, proždrije skakavac, što ostavi skakavac, proždrije gusjenica, što ostavi gusjenica, proždrije ljupilac."},{"v":5,"t":"Probudite se, pijanice, i plačite! Sve vinopije, tužite za novim vinom: iz usta vam je oteto."},{"v":6,"t":"Jer prekri moju zemlju narod moćan i bezbrojan; zubi su mu kao zubi lavlji, očnjaci mu kao u lavice."},{"v":7,"t":"Opustoši mi lozu vinovu i polomi smokve moje; oguli ih i razbaca, grane su im pobijeljele."},{"v":8,"t":"Plačite k'o djevica odjevena u kostrijet za zaručnikom svojim."},{"v":9,"t":"Nestade prinosnice i ljevanice iz Doma Jahvina. Tuže svećenici, sluge Jahvine."},{"v":10,"t":"Opustošeno polje, zemlja poharana. Poharano žito, vino propade, presahnu ulje."},{"v":11,"t":"Tugujte, težaci, kukajte, vinogradari, za pšenicom i za ječmom, jer propade žetva poljska."},{"v":12,"t":"Loza usahnu, uvenu smokva, mogranj, palma i jabuka: svako se drvo poljsko sasuši. Da, nestade radosti između sinova ljudskih."},{"v":13,"t":"Svećenici, opašite kostrijet i tužite! Službenici žrtvenika, naričite! Dođite, prenoćite u kostrijeti, službenici Boga mojeg! Jer iz Doma Boga našeg nesta prinosnice i ljevanice!"},{"v":14,"t":"Naredite sveti post, proglasite zbor svečani; starješine, saberite sve stanovnike zemlje u kuću Jahve, Boga svojeg. Zavapijte Jahvi:"},{"v":15,"t":"“Jao dana!” Jer Jahvin dan je blizu i dolazi k'o pohara od Svevišnjeg."},{"v":16,"t":"Ne iščeznu li hrana pred našim očima? Nije li nestalo radosti i sreće iz Doma Boga našega?"},{"v":17,"t":"Istrunu zrnje pod grudama; puste su žitnice, porušene spreme jer žita nesta."},{"v":18,"t":"Kako li stoka uzdiše! Krda goveda podivljala lutaju jer im nema paše. Čak i stada ovaca kaznu podnose."},{"v":19,"t":"Tebi, Jahve, vapijem: oganj popali pašnjake pustinjske, plamen sažga sva stabla poljska."},{"v":20,"t":"Čak i zvijeri čeznu za tobom, jer presušiše potoci, oganj popali pašnjake pustinjske."}]},"2":{"hr":[{"v":1,"t":"Trubite u trubu na Sionu! Dižite uzbunu na svetoj mi gori! Neka svi stanovnici zemlje dršću, jer dolazi Jahvin dan. Da, on je blizu."},{"v":2,"t":"Dan pun mraka i tmine, dan oblačan i crn. K'o zora po gorama se prostire narod jak i mnogobrojan, kakva ne bje nikad prije, niti će ga igda biti do vremena najdaljih."},{"v":3,"t":"Pred njim oganj proždire, za njim plamen guta. Zemlja je k'o vrt rajski pred njim, a za njim pustinja tužna. Ništa mu ne umiče."},{"v":4,"t":"Nalik su na konje, jure poput konjanika."},{"v":5,"t":"Buče kao bojna kola, po gorskim vrhuncima skaču, pucketaju k'o plamen ognjeni kad strnjiku proždire, kao vojska jaka u bojnome redu."},{"v":6,"t":"Pred njima narodi dršću i svako lice problijedi."},{"v":7,"t":"Skaču k'o junaci, k'o ratnici se na zidove penju. Svaki ide pravo naprijed, ne odstupa od svog puta."},{"v":8,"t":"Ne tiskaju jedan drugog, već svak' ide svojom stazom. Padaju od strijela ne kidajuć' redova."},{"v":9,"t":"Na grad navaljuju, na zidine skaču, penju se na kuće i kroz okna ulaze poput lupeža."},{"v":10,"t":"Pred njima se zemlja trese, nebo podrhtava, sunce, mjesec mrčaju, zvijezdama se trne sjaj."},{"v":11,"t":"I Jahve glas svoj šalje pred vojsku svoju. I odista, tabor mu je silno velik, zapovijedi njegove moćan izvršitelj. Da, velik je Jahvin dan i vrlo strašan. Tko će ga podnijeti?"},{"v":12,"t":"“Al' i sada - riječ je Jahvina - vratite se k meni svim srcem svojim posteć', plačuć' i kukajuć'.”"},{"v":13,"t":"Razderite srca, a ne halje svoje! Vratite se Jahvi, Bogu svome, jer on je nježnost sama i milosrđe, spor na ljutnju, a bogat dobrotom, on se nad zlom ražali."},{"v":14,"t":"Tko zna neće li se opet ražaliti, neće li blagoslov ostaviti za sobom! Prinose i ljevanice Jahvi, Bogu našemu!"},{"v":15,"t":"Trubite u trubu na Sionu! Sveti post naredite, oglasite zbor svečani,"},{"v":16,"t":"narod saberite, posvetite zbor. Saberite starce, sakupite djecu, čak i nejač na prsima. Neka ženik iziđe iz svadbene sobe a nevjesta iz odaje."},{"v":17,"t":"Između trijema i žrtvenika neka tuže svećenici, sluge Jahvine. Neka mole: “Smiluj se, Jahve, svojem narodu! Ne prepusti baštine svoje sramoti, poruzi naroda. Zašto da se kaže među narodima: Gdje im je Bog?”"},{"v":18,"t":"Tad Jahve, ljubomoran na zemlju svoju, smilova se svom narodu."},{"v":19,"t":"Odgovori Jahve svojem narodu: “Šaljem vam, evo, žita, vina i ulja da se njime nasitite. Nikad više neću pustiti da budete na sramotu narodima."},{"v":20,"t":"Protjerat ću Sjevernjaka od vas daleko, odagnat ga u zemlju suhu i pustu, prethodnicu u Istočno more, zalaznicu u Zapadno more. Dići će se njegov smrad, dizat će se trulež njegova.” (Jer učini stvari velike.)"},{"v":21,"t":"O zemljo, ne boj se! Budi sretna, raduj se, jer Jahve učini djela velika."},{"v":22,"t":"Zvijeri poljske, ne bojte se; pašnjaci u pustinji opet se zelene, voćke daju rod, smokva i loza nose izobila."},{"v":23,"t":"Sinovi sionski, radujte se, u Jahvi se veselite, svojem Bogu; jer vam daje kišu jesensku u pravoj mjeri, izli na vas kišu, jesensku i proljetnu kišu kao nekoć."},{"v":24,"t":"Gumna će biti puna žita, kace će se prelijevati od vina i ulja."},{"v":25,"t":"“Nadoknadit ću vam godine koje izjedoše skakavac, gusjenica, ljupilac i šaška, silna vojska moja što je poslah na vas.”"},{"v":26,"t":"Jest ćete izobila, jest ćete do sita, slavit ćete ime Jahve, svojeg Boga, koji je s vama čudesno postupao. (“Moj se narod neće postidjeti nikad više.”)"},{"v":27,"t":"“Znat ćete da sam posred Izraela, da sam ja Jahve, vaš Bog, i nitko više. Moj se narod neće postidjeti nikad više.”"}]},"3":{"hr":[{"v":1,"t":"“Poslije ovoga izlit ću Duha svoga na svako tijelo, i proricat će vaši sinovi i kćeri, vaši će starci sanjati sne, a vaši mladići gledati viđenja."},{"v":2,"t":"Čak ću i na sluge i sluškinje izliti Duha svojeg u dane one."},{"v":3,"t":"Pokazat ću znamenja na nebu i zemlji, krv i oganj i stupove dima.”"},{"v":4,"t":"Sunce će se prometnut' u tminu a mjesec u krv, prije nego svane Jahvin dan, velik i strašan."},{"v":5,"t":"Svi što prizivaju ime Jahvino spašeni će biti, jer će na brdu Sionu i u Jeruzalemu biti spasenje, kao što Jahve reče, a među preživjelima oni koje Jahve pozove."}]},"4":{"hr":[{"v":1,"t":"“Jer, gle, u one dane i u ono vrijeme, kad okrenem udes Judeji i Jeruzalemu,"},{"v":2,"t":"sakupit ću sve narode i povesti ih u dolinu Jošafat. Ondje ću im suditi zbog Izraela, naroda mog i moje baštine, koju rastjeraše među narode i razdijeliše moju zemlju među se."},{"v":3,"t":"Baciše ždrijeb za moj narod; davali su dječake za bludnice, djevojke prodavali za vino i pili.”"},{"v":4,"t":"“I vi, Tire i Sidone, što hoćete od mene? I vi, filistejski kraljevi? Želite li mi se osvetiti? Ako se budete svetili meni, osveta će brzo na vaše glave."},{"v":5,"t":"Na vas što mi oteste srebro i zlato, što odnesoste bogate mi riznice u svoje hramove,"},{"v":6,"t":"na vas koji prodavaste Grcima sinove Jude i Jeruzalema da biste ih otjerali od domovine njihove."},{"v":7,"t":"Gle, ja ih kanim dići s mjesta gdje god ih prodaste, i učinit ću da vam zločin vaš padne na glave."},{"v":8,"t":"Prodat ću vaše sinove i kćeri sinovima Judinim, a oni će ih prodat' Sabejcima, daleku narodu. Jer Jahve reče!”"},{"v":9,"t":"Razglasite ovo među narodima! Posvetite se za rat! Dižite junake! Naprijed, navalite, svi ratnici!"},{"v":10,"t":"Prekujte raonike u mačeve, kosire u koplja, nek' slabić kaže: “Junak sam!”"},{"v":11,"t":"Pohitajte i dođite, svi okolni narodi, i ondje se saberite! (Jahve, onamo pošalji svoje junake!)"},{"v":12,"t":"“Budite se, narodi, stupajte u Dolinu Jošafat, jer ću ondje sjesti da sudim svim okolnim narodima."},{"v":13,"t":"Hvatajte se srpa: ljetina je zrela. Ustanite, siđite: tijesak je pun, prelijevaju se kace, jer je velika zloća njihova.”"},{"v":14,"t":"Mnoštvo, mnoštvo u Dolini Odluke! Da, blizu je dan Jahvin u Dolini Odluke!"},{"v":15,"t":"Sunce i mjesec pomrčaše, zvijezde potamnješe."},{"v":16,"t":"Jahve grmi sa Siona, glas diže iz Jeruzalema; nebo se i zemlja tresu. Ali je Jahve utočište svome narodu i zaštita sinovima Izraela."},{"v":17,"t":"“Znat ćete tada da sam ja Jahve vaš Bog što stoluje na Sionu, svetoj gori svojoj. Jeruzalem će biti svetište, tuđinac više neće kroza nj proći.”"},{"v":18,"t":"Kad dođe taj dan, kapat će gore moštom, iz bregova će brizgati mlijeko, kroza sva korita riječna u Judeji voda će proteći. Vrelo će šiknuti iz kuće Jahvine da natopi Dolinu sitimsku."},{"v":19,"t":"Egipat će opustjeti, Edom će postati beživotna pustinja zbog nasilja učinjena sinovima Judinim, jer proliše krv nevinu u njihovoj zemlji."},{"v":20,"t":"Judeja će dovijek biti naseljena i Jeruzalem u sva koljena."},{"v":21,"t":"“Osvetit ću krv njihovu za koju se nisam još osvetio.” Jahve će dići Dom svoj na Sionu."}]}},"AMO":{"1":{"hr":[{"v":1,"t":"Riječi Amosa, pastira iz Tekoe. Njegova viđenja o Izraelu u doba judejskoga kralja Uzije i Jeroboama, sina Joaša, izraelskoga kralja, dvije godine prije potresa."},{"v":2,"t":"Veli on: “Jahve grmi sa Siona, iz Jeruzalema glas mu se ori; stočarski pašnjaci tuže i suši se vrh Karmela.”"},{"v":3,"t":"Ovako govori Jahve: “Za tri zločina Damaska, za četiri zločina, odluka je neopoziva: jer su vrhli Gilead cijepom željeznim,"},{"v":4,"t":"pustit ću oganj na dom Hazaelov da sažeže Ben-Hadadove dvorce;"},{"v":5,"t":"polomit ću zasune Damaska, istrijebiti živalj Bikat Avena i žezlonošu iz Bet Edena; narod će aramski u ropstvo u Kir,” veli Jahve Gospod."},{"v":6,"t":"Ovako govori Jahve: “Za tri zločina Gaze, za četiri zločina, odluka je neopoziva: jer odvedoše sve u izgnanstvo i Edomu predadoše,"},{"v":7,"t":"pustit ću oganj na zidine Gaze da dvorce joj sažeže."},{"v":8,"t":"Istrijebit ću žitelje ašdodske i žezlonošu iz Aškelona. Pružit ću ruku na Ekron da ostatak filistejski pogine,” veli Jahve Gospod."},{"v":9,"t":"Ovako govori Jahve: “Za tri zločina Tira, za četiri zločina, odluka je neopoziva: jer predade sve izgnanike Edomu i nisu se sjetili bratskog saveza,"},{"v":10,"t":"pustit ću oganj na zidove Tira da sažeže njihove dvorce.”"},{"v":11,"t":"Ovako govori Jahve: “Za tri zločina Edoma, za četiri zločina, odluka je neopoziva: jer gonjaše brata mačem prigušujuć' samilost svoju, jer gnjev svoj potpirivaše jednako, jer poticaše bijes svoj,"},{"v":12,"t":"pustit ću oganj na Teman da sažeže dvorce u Bosri.”"},{"v":13,"t":"Ovako govori Jahve: “Za tri zločina Amonovih sinova, za četiri zločina, odluka je neopoziva: jer parahu trudnice gileadske da rašire granice svoje,"},{"v":14,"t":"potpalit ću oganj na zidinama Rabe da dvorce joj sažeže, s bojnom grajom u dan rata, s burama u dan vihora,"},{"v":15,"t":"a kralj će im otić' u izgnanstvo, on i knezovi njegovi s njime,” veli Jahve Gospod."}]},"2":{"hr":[{"v":1,"t":"Ovako govori Jahve: “Za tri zločina Moaba, za četiri zločina, odluka je neopoziva: jer kosti edomskoga kralja spališe u vapno,"},{"v":2,"t":"pustit ću oganj na Moab da dvorce kerijotske sažeže, a Moab će umrijet u metežu, s bojnom grajom i sa zvukom trube;"},{"v":3,"t":"oborit ću suca u njemu i poklati sve knezove s njime,” veli Jahve Gospod."},{"v":4,"t":"Ovako govori Jahve: “Za tri zločina Judina, za četiri zločina, odluka je neopoziva: jer odbaciše Zakon Jahvin i njegovih se odredaba ne držahu; zavedoše ih lažni bozi za kojima iđahu očevi njihovi,"},{"v":5,"t":"pustit ću oganj na Judu, da sažeže dvorce jeruzalemske.”"},{"v":6,"t":"Ovako govori Jahve: “Za tri zločina Izraela, za četiri zločina, odluka je neopoziva: jer prodavahu pravednika za srebro i nevoljnika za sandale;"},{"v":7,"t":"jer gaze po glavi siromahu i sirotinju na zlo vode; sin i otac k istoj djevojci idu da oskvrnu moje sveto ime;"},{"v":8,"t":"i na haljinama u zalog uzetima leže kraj svakoga žrtvenika; i piju vino oglobljenih u Domu Boga svojega."},{"v":9,"t":"Ja pred njima istrijebih Amorejce visoke k'o cedar, jake poput hrašća, ja uništih i plod na njima i korijen pod njima."},{"v":10,"t":"Ja vas izvedoh iz zemlje egipatske i četrdeset vas godina vodih po pustinji da zaposjednete zemlju amorejsku."},{"v":11,"t":"Ja podigoh proroke izmeđ' vaših sinova i nazirejce među vašim mladićima. Nije li tako, sinovi Izraelovi? - riječ je Jahvina."},{"v":12,"t":"Al' vi nagnaste nazirejce da vino piju, a prorocima zapovjediste: 'Ne prorokujte!'"},{"v":13,"t":"Gle, ja vas prignječujem o tlo pod vama, k'o što vršalice gnječe klasje;"},{"v":14,"t":"neće biti bijega brzu, jaka neće učvrstiti snaga, junak se neće spasiti,"},{"v":15,"t":"strijelac se neće održati, hitri trkač pobjeć' neće, nit' će jahač umaći,"},{"v":16,"t":"najsrčaniji će ratnici bježat' nagi onog dana” - riječ je Jahvina."}]},"3":{"hr":[{"v":1,"t":"Počujte, sinovi Izraelovi, ovu riječ koju Jahve zbori protiv vas, protiv svakoga roda što ga izvedoh iz zemlje egipatske:"},{"v":2,"t":"“Među svim plemenima zemaljskim samo vas poznah, zato ću vas kazniti za sve grijehe vaše.”"},{"v":3,"t":"Idu li dvojica zajedno da se ne dogovore?"},{"v":4,"t":"Riče li lav u šumi ako plijena nema? Reži li lavić u brlogu ako ništa ne ulovi?"},{"v":5,"t":"Pada l' ptica na zemlju ako na njoj zamke nema? Diže li se mreža sa zemlje ako se ništa ne uhvati?"},{"v":6,"t":"Trubi li truba po gradu da se narod ne uzbuni? Hoće li kob pogoditi grad ako je Jahve ne pošalje?"},{"v":7,"t":"Ništa ne čini Jahve Gospod a da osnove svoje ne otkrije slugama svojim prorocima."},{"v":8,"t":"Lav riče: tko da se ne prestravi? Gospod Jahve govori: tko da ne prorokuje?"},{"v":9,"t":"Proglasite ovo po dvorcima asirskim i po dvorcima u zemlji egipatskoj; recite: “Skupite se na planini Samarije, pogledajte velik nered u njoj i tlačenje posred nje.”"},{"v":10,"t":"Jer ne znaju činiti pravo - riječ je Jahvina - u dvorcima gomilaju nasilje i tlačenje."},{"v":11,"t":"Stog ovako govori Jahve Gospod: “Neprijatelj će opkoliti zemlju, utvrde će tvoje razvaliti, tvoje dvorce oplijeniti.”"},{"v":12,"t":"Ovako govori Jahve: “Kao kad pastir istrgne dvije golijeni ili komadić uha iz lavljih ralja, tako će se istrgnuti sinovi Izraelovi koji sjede u Samariji na rubu počivaljke i na divanima.”"},{"v":13,"t":"Čujte i posvjedočite protiv doma Jakovljeva - riječ je Jahve Gospoda, Boga nad Vojskama:"},{"v":14,"t":"“Onoga dana kad kaznim Izraela za zločine, kaznit ću i žrtvenike betelske; žrtvenički će se rozi odlomiti i na tlo popadati."},{"v":15,"t":"Razorit ću zimsku kuću i ljetnu kuću, propast će kuće bjelokosne. Mnogih će kuća nestati” - riječ je Jahvina."}]},"4":{"hr":[{"v":1,"t":"Počujte ovu riječ, krave bašanske, što boravite na samarijskoj gori, tlačite potrebite, ugnjetavate siromahe, govorite muževima: “Donesi da pijemo!”"},{"v":2,"t":"Zakle se Jahve Gospod svetošću svojom: “Dolaze vam, evo, dani kad će vas izvlačiti kukama, a posljednju od vas ostima."},{"v":3,"t":"Kroz pukotine ćete izlaziti, ne obziruć' se nikamo, i biti bačene prema Hermonu” - riječ je Jahvina."},{"v":4,"t":"“Idite samo u Betel i griješite, u Gilgal i množite grijehe svoje! Prinosite svakog jutra žrtve, i desetine svaki treći dan."},{"v":5,"t":"Palite tijesto uskislo na žrtvu zahvalnicu, oglasite žrtve dragovoljne, razglasite ih, jer to volite, sinovi Izraelovi” - riječ je Jahve Gospoda."},{"v":6,"t":"“Zato dadoh da vam zubi čisti ostanu u svim gradovima vašim, ostavih vas bez kruha u svim selima vašim; pa ipak se ne obratiste k meni” - riječ je Jahvina."},{"v":7,"t":"“Uskratih vam i kišu tri mjeseca prije žetve; pustih da kiši na jedan grad, al' ne i na drugi; jedno bi se polje nakvasilo, a drugo bi se - na koje ne pustih kiše - sasušilo."},{"v":8,"t":"Dva-tri grada lutahu tako u treći da piju vode, ali se ne mogoše napiti, pa ipak se ne obratiste k meni” - riječ je Jahvina."},{"v":9,"t":"“Udarah vas snijeću i medljikom, sasuših vam vrtove i vinograde, proždriješe vam skakavci smokve i masline, pa ipak se ne obratiste k meni” - riječ je Jahvina."},{"v":10,"t":"“Poslah na vas kugu poput kuge egipatske; mladiće vaše poklah mačem, a konji vam bjehu k'o plijen odvedeni; napunih vam nosnice smradom iz tabora vašega, pa ipak se ne obratiste k meni” - riječ je Jahvina."},{"v":11,"t":"“Obarah vas k'o što Bog obori Sodomu i Gomoru, bijaste k'o glavnja iz ognja istrgnuta, pa ipak se ne obratiste k meni” - riječ je Jahvina."},{"v":12,"t":"“Stog ću, Izraele, ovako s tobom postupiti, i jer ću tako s tobom postupiti, pripravi se, Izraele, da susretneš Boga svoga!”"},{"v":13,"t":"Jer, gle, on sazda planine i stvori vjetar, otkriva čovjeku misao svoju, on tvori zoru i mrak, i penje se na vrh visova zemaljskih, Jahve, Bog nad Vojskama, njegovo je ime."}]},"5":{"hr":[{"v":1,"t":"Počujte ovu riječ što je iznosim protiv vas, naricaljku, dome Izraelov:"},{"v":2,"t":"Pade i više neće ustati djevica izraelska. Na tlu svojem ona leži, nikog da je digne."},{"v":3,"t":"Jer ovako govori Jahve Gospod domu Izraelovu: u gradu iz kojeg izlažaše tisuća, ostat će stotina, iz kojeg izlažaše stotina, ostat će ih deset."},{"v":4,"t":"Jer ovako govori Jahve domu Izraelovu: “Tražite i živjet ćete."},{"v":5,"t":"Ne tražite Betela, ne idite u Gilgal, ne putujte u Beer Šebu, jer će Gilgal bit odveden u izgnanstvo, a Betel će se prometnuti u ništa."},{"v":6,"t":"Tražite Jahvu i živjet ćete, il' će ko' oganj zahvatiti kuću Josipovu i sažeć' je, a u Betelu nikog da plamen ugasi.”"},{"v":7,"t":"Jao onima koji pravdu pretvaraju u pelin, u prah bacaju poštenje!"},{"v":8,"t":"On napravi Vlašiće i Štapce, on obrće mrak u zoru, a dan u najglušu noć. On saziva morske vode i valja ih preko lica zemlje. Jahve mu je ime."},{"v":9,"t":"Nenadano šalje pustoš na tvrđavu i utvrdi propast nosi."},{"v":10,"t":"Mrze čovjeka što na vratima pravdu dijeli i grde onog što zbori pošteno."},{"v":11,"t":"Stoga, jer gazite siromaha, dižući od njega porez u žitu - u kućama što ih sazdaste od tesanika nikad živjet' nećete; iz ljupkih vinograda što ih posadiste nikad nećete piti vina."},{"v":12,"t":"Jer znam mnoge vaše zločine, i vaše grijehe pregoleme: tlačite pravednika i primate mito, odbijajuć' siromaha na gradskim vratima."},{"v":13,"t":"Mudrac šuti u ovo vrijeme, jer vremena su tako zla."},{"v":14,"t":"Tražite dobro, a ne zlo, da biste živjeli, i da Jahve, Bog nad Vojskama, odista s vama bude kao što velite da jest."},{"v":15,"t":"Mrzite zlo, ljubite dobro, držite pravicu na gradskim vratima, pa će se možda Jahve, Bog nad Vojskama, smilovat' ostatku Josipovu."},{"v":16,"t":"Stog ovako govori Jahve, Bog nad Vojskama, Gospod: “Na svakom će trgu biti kuknjava, po svim će ulicama zapomagati: 'Jao! Jao!' Težake će sazvat' da jauču, narikače da nariču,"},{"v":17,"t":"bit će jauk u svakom vinogradu, jer ću proći posred tebe” - veli Jahve."},{"v":18,"t":"“Jao vama što žudite za danom Jahvinim! Što će vam biti dan Jahvin? Tama, a ne svjetlost."},{"v":19,"t":"Bit će vam k'o onom što uteče lavljim raljama, a sretne ga medvjed; koji uđe u kuću i stavi ruku na zid, a ujede ga zmija."},{"v":20,"t":"Neće li dan Jahvin biti tama, a ne svjetlost? Mrklina, a ne sunčan sjaj?"},{"v":21,"t":"Mrzim i prezirem vaše blagdane i nisu mi mile vaše svečanosti."},{"v":22,"t":"Paljenice kad mi prinosite, prinosnice mi vaše nisu mile, na pričesnice se od ugojenih telaca vaših i ne osvrćem."},{"v":23,"t":"Uklonite od mene dreku svojih pjesama, neću da slušam zvuke vaših harfa."},{"v":24,"t":"Pravda nek' poteče kao voda i pravica k'o bujica silna."},{"v":25,"t":"Prinosiste li mi žrtve i prinos u pustinji četrdeset godina, dome Izraelov?"},{"v":26,"t":"Nosit ćete Sikuta, svoga kralja, i Kevana, boga svoga, likove što ih sebi napraviste,"},{"v":27,"t":"dok vas budem odvodio onkraj Damaska,” govori Jahve - Bog nad Vojskama njemu je ime."}]},"6":{"hr":[{"v":1,"t":"Jao bezbrižnima na Sionu i spokojnima na samarijskoj gori, nazvanima “prvina naroda”, kojima se obraća dom Izraelov."},{"v":2,"t":"Krenite u Kalnu i vidite, idite odande u Veliki Hamat, siđite u Gat filistejski. Jeste li bolji od tih kraljevstava? Je li im područje veće od vašega?"},{"v":3,"t":"Mislite: daleko je kobni dan, a primičete vlast nasilja."},{"v":4,"t":"Ležeći na bjelokosnim posteljama, na počivaljkama izvaljeni, jedu janjad iz stada i telad iz staje;"},{"v":5,"t":"deru se uza zvuk harfe, izumljuju glazbala k'o David,"},{"v":6,"t":"piju vino iz vrčeva i mažu se najfinijim uljem, al' za slom Josipov ne mare."},{"v":7,"t":"Stog će prvi sad biti prognani; umuknut će veselje raskošnika."},{"v":8,"t":"Zakle se Gospod Jahve samim sobom - riječ je Jahve, Boga nad Vojskama: “Gnušam se oholosti Jakovljeve i mrzim dvorce njegove, predat ću grad i sve u njemu.”"},{"v":9,"t":"Ako i deset ljudi ostane u jednoj kući, umrijet će."},{"v":10,"t":"Rođak će i spaljivač prionuti da iznesu kosti iz kuće; ako bi tko upitao onog u kutu kuće: “Je li još tko ostao s tobom?” on će odvratiti: “Ne! Pst! Jahvino se ime ne smije spomenuti.”"},{"v":11,"t":"Jer, gle, Jahve zapovjedi, i velika se kuća ruši u komade, mala se kuća ori u komadiće."},{"v":12,"t":"Jure li konji po litici, ore li se more volovima, da vi pretvarate pravdu u otrov a plod pravednosti u pelin?"},{"v":13,"t":"Vi se radujete Lo Dabaru kad velite: “Nismo li svojom snagom zauzeli Karnajim?”"},{"v":14,"t":"“Ha, evo, dome Izraelov, dižem na te - riječ je Jahve, Boga nad Vojskama - narod što će vas tlačiti od Ulaza hamatskoga do Pustinjskog potoka.”"}]},"7":{"hr":[{"v":1,"t":"Evo što mi pokaza Jahve Gospod: gle, sazda skakavce kad otava poče nicati, otava nakon kraljevske kosidbe."},{"v":2,"t":"Kad izjedoše sav zemaljski usjev, rekoh: “Jahve Gospode, oprosti, molim te! Kako će Jakov preživjeti onako malen?”"},{"v":3,"t":"I Jahve se stoga pokaja: “Neće biti”, reče Jahve."},{"v":4,"t":"Evo što mi pokaza Jahve Gospod: Gle, Jahve Gospod pozva oganj da kažnjava; već proždrije veliki Bezdan i uprav poče gutati polje."},{"v":5,"t":"A ja ću: “Stani, Jahve Gospode, molim te! Kako će Jakov preživjeti onako malen?”"},{"v":6,"t":"I Jahve se stog pokaja: “Ni ovoga neće biti”, reče Jahve Gospod."},{"v":7,"t":"Evo što mi Jahve Gospod pokaza: gle, čovjek stoji na zidu, u ruci mu visak."},{"v":8,"t":"“Što vidiš, Amose?” - upita me Jahve. “Visak”, rekoh. Tada Gospod reče: “Evo, izmjerit ću viskom svoj narod izraelski; neću ga više štedjeti."},{"v":9,"t":"Razorit će se uzvišice Izakove, opustjeti svetišta izraelska, i s mačem ću ustati na kuću Jeroboamovu.”"},{"v":10,"t":"Amasja, svećenik betelski, poruči izraelskom kralju Jeroboamu: “Amos se urotio protiv tebe usred doma Izraelova; zemlja ne može više podnijeti njegovih riječi."},{"v":11,"t":"Jer ovako on govori: 'Jeroboam će poginuti od mača, a Izrael će iz svoje zemlje u izgnanstvo.'”"},{"v":12,"t":"Amasja reče Amosu: “Odlazi, vidioče! Bježi u zemlju Judinu, ondje jedi kruh i ondje prorokuj!"},{"v":13,"t":"Ali u Betelu da više nisi prorokovao, jer ovo je kraljevsko svetište, kraljevski hram.”"},{"v":14,"t":"“Nisam bio prorok ni proročki sin” - odgovori Amos Amasji - “bio sam stočar i gajio sam divlje smokve:"},{"v":15,"t":"ali me Jahve uze od stada i Jahve mi reče: 'Idi, prorokuj mojemu narodu Izraelu.'"},{"v":16,"t":"Sada čuj riječ Jahvinu. Ti veliš: 'Ne prorokuj protiv Izraela, ne proriči protiv doma Izakova.'"},{"v":17,"t":"Zato ovako govori Jahve: 'Tvoja će žena bludničit' po gradu, sinovi tvoji i kćeri od mača će pasti, tvoja će se zemlja užetom razdijeliti, a ti ćeš umrijeti na nečistu tlu, i Izrael će otići u izgnanstvo iz svoje zemlje.'”"}]},"8":{"hr":[{"v":1,"t":"Evo što mi pokaza Jahve Gospod: gle, kotarica zrela ploda:"},{"v":2,"t":"“Što vidiš, Amose?” - upita me. “Kotaricu zrela ploda”, rekoh. Tada mi Jahve reče: “Moj narod izraelski dozreo je za propast; neću ga više štedjeti."},{"v":3,"t":"I hramske će pjevačice jaukati toga dana - riječ je Jahve Gospoda - bit će mnoštvo trupla, svuda će se bacati.”"},{"v":4,"t":"Slušajte ovo, vi što gazite potrebnika i satirete uboge u zemlji!"},{"v":5,"t":"Kažete: “Kad li će mlađak proći, da prodamo žito, i subota, da tržimo pšenicu. Smanjujuć' efu, povećavajući šekel, da varamo krivim mjerama:"},{"v":6,"t":"da kupimo siromaha za novac, potrebita za sandale, i da prodajemo otražak od žita."},{"v":7,"t":"Zakle se Jahve Ponosom Jakovljevim: “Dovijeka neću zaboraviti nijednoga vašeg djela.”"},{"v":8,"t":"Neće l' se od toga zemlja potresti, protužiti svi njeni stanovnici, neće li se sva podići kao Nil, spustiti kao Rijeka egipatska?"},{"v":9,"t":"“Toga ću dana - riječ je Jahve Gospoda - učiniti da sunce zapadne u podne, i pomračit ću zemlju u po bijela dana."},{"v":10,"t":"Okrenut ću svetkovine vaše u kuknjavu i sve vaše pjevanje u tužaljku; obući ću u kostrijet svako bedro, oćelavit ću svaku glavu. Bit će kao kad se tuži za jedincem, i što ostane, bit će kao dan gorčine.”"},{"v":11,"t":"“Evo, dani dolaze - riječ je Jahve Gospoda - kad ću poslati glad na zemlju, ne glad kruha ni žeđ vode, već slušanja riječi Jahvine."},{"v":12,"t":"Tumarat će od mora do mora, od sjevera do istoka potucati se ištući riječ Jahvinu, ali je neće naći."},{"v":13,"t":"U onaj će dan obamirati od žeđi lijepe djevojke i mladići."},{"v":14,"t":"Koji se kunu Grijehom samarijskim i zaklinju se: 'Tako živ bio bog tvoj, Dane!' i: 'Tako živ bio Ljubimac tvoj, Beer Šebo!' oni će pasti i nikad ustati neće.”"}]},"9":{"hr":[{"v":1,"t":"Vidjeh Gospoda gdje stoji kraj žrtvenika i govori: “Udari u glavice stupova, neka se pragovi zatresu! Svima ću satrti glave, što ostane, pod mač ću udariti. Nijedan neće uteći, nitko se neće spasiti."},{"v":2,"t":"Zariju li se i u Podzemlje, iščupat će ih ruka moja. Popnu li se i na nebo, odande ću ih skinuti."},{"v":3,"t":"Ako se sakriju i navrh Karmela, naći ću ih i pohvatati. Ako se od mog pogleda na dno morsko skriju, zapovjedit ću Zmaju da ih proždre."},{"v":4,"t":"Ako i u izgnanstvo odu pred neprijateljem, naredit ću maču da ih sasiječe; upravit ću oči na njih, ali na nesreću, ne na dobro.”"},{"v":5,"t":"Jahve, Gospod nad Vojskama... on dodirne zemlju i ona se potrese, svi joj stanovnici protuže; diže se sva poput Nila i spušta k'o Rijeka egipatska."},{"v":6,"t":"On sazda sebi prijesto na nebesima, i svod svoj na zemlji osnova; on poziva morske vode i lijeva ih zemlji preko lica - Jahve mu je ime."},{"v":7,"t":"“Sinovi Izraelovi, niste li za me kao i Kušani” - riječ je Jahvina. “Ne izvedoh li ja Izraela iz zemlje egipatske, kao Filistejce iz Kaftora i Aramejce iz Kira?”"},{"v":8,"t":"Gle, oči Jahve Gospoda uprte su na grešno kraljevstvo, izbrisat će ga s lica zemlje. “Ipak neću sasvim zatrti dom Jakovljev” - riječ je Jahvina."},{"v":9,"t":"“Jer, gle, zapovijed ću dati i rastresti dom Izraelov među sve narode, k'o što se trese žito u rešetu, da ni zrnce na zemlju ne padne."},{"v":10,"t":"Svi grešnici naroda moga od mača će pasti, svi koji kažu: 'Nije blizu i neće nas stići nesreća.'”"},{"v":11,"t":"“U dan ću onaj podići raspalu kolibu Davidovu, zatvorit' joj pukotine, popraviti mjesta ruševna, opet je sazidati k'o u stara vremena,"},{"v":12,"t":"da osvoje ostatak Edoma i svih naroda nad kojima je zazvano ime moje” - riječ je Jahve Gospoda, tvorca svega toga."},{"v":13,"t":"“Evo dolaze dani - riječ je Jahvina - kada će orač stizat' žeteoca, mastilac grožđa sijača, kad će planine procuriti mladim vinom i svi se bregovi prelijevati njime."},{"v":14,"t":"Okrenut ću sudbinu naroda moga Izraela: obnovit će gradove srušene i živjeti u njima, saditi vinograde i vino im piti, zasaditi vrtove i jesti njihov rod."},{"v":15,"t":"Posadit ću ih u zemlju njihovu i nikad se više neće iščupati iz zemlje koju im dadoh” - veli Jahve, Bog tvoj."}]}},"OBA":{"1":{"hr":[{"v":1,"t":"Viđenje Obadijino. Ovako govori Jahve Gospod Edomu! Čuli smo vijest od Jahve, glasnik bi poslan k narodima: “Ustajte! Na nj u boj krenimo!”"},{"v":2,"t":"“Jer gle, učinit ću te najmanjim među narodima, prezrenim veoma."},{"v":3,"t":"Uznositost srca tvoga zavela te, tebe što živiš u pećinama kamenim, u visoku stanu svojemu, i u srcu svome zboriš: 'Tko li će me na zemlju skinuti?'"},{"v":4,"t":"Da se vineš k'o orao, gnijezdo sviješ među zvijezdama, i odande skinut ću te” - riječ je Jahvina."},{"v":5,"t":"“Dođu li k tebi lupeži il' kradljivci noćni, kako li ćeš biti oplijenjen! Neće li te okrasti po miloj volji? Dođu li trgači k tebi, zar će i pabirka ostaviti?"},{"v":6,"t":"Kako li Edom bješe pretresen, skrivena mu skrovišta pretražena!"},{"v":7,"t":"Do granica te potjeraše, svi te saveznici tvoji prevariše, nadvladaše te tvoji prijatelji! Oni što kruh tvoj jedu zamku ti staviše: 'Sasvim je bez uma!'"},{"v":8,"t":"Neću li u dan onaj - riječ je Jahvina - uništit' mudraca u Edomu i razum iz gore Ezavljeve?"},{"v":9,"t":"Ratnike tvoje, Temane, užas će spopasti, i posljednji će biti istrijebljen na gori Ezavljevoj.” “Za pokolj"},{"v":10,"t":"i nasilje nad bratom svojim Jakovom sram će te pokriti i nestat ćeš zasvagda."},{"v":11,"t":"U dan onaj kad stajaše postrance, dok mu tuđinci blago odvodiše, dok stranci ulažahu na vrata njegova i ždrijeb bacahu za Jeruzalem, ti bijaše kao jedan od njih."},{"v":12,"t":"Ne naslađuj se bratu u dan nesreće njegove! Ne likuj nad sinovima judejskim u dan propasti njine! Ne razvaljuj usta u dan tjeskobni!"},{"v":13,"t":"Ne provaljuj na vrata naroda moga u dan nesreće njegove! Ne naslađuj se njegovom propašću u dan nesreće njegove! Ne pružaj ruke na imanje njegovo u dan nesreće njegove!"},{"v":14,"t":"Ne stoj na raskršćima da pobiješ njegove bjegunce! Ne izdaji preživjelih njegovih u dan tjeskobni!”"},{"v":15,"t":"Jer blizu je Jahvin dan svima narodima! Dat će ti se milo za drago, tvoja će djela na tvoju glavu pasti."},{"v":16,"t":"“Jest, kako vi piste na svetoj mi gori, pit će svi narodi bez oduška, pit će i iskapiti - i bit će k'o da ih nigda bilo nije."},{"v":17,"t":"Al' na gori Sionu bit će spasenici - postat će sveta - i dom će Jakovljev baštiniti svoju baštinu."},{"v":18,"t":"Dom će Jakovljev biti oganj, dom Josipov plamen, dom Ezavljev strnjika. Potpalit će ga i proždrijeti, i od doma Ezavljeva nitko neće ostati” - riječ je Jahvina."},{"v":19,"t":"Žitelji negepski baštinit će goru Ezavljevu, žitelji Šefele zemlju filistejsku; baštinit će kraj Efrajimov i kraj samarijski, a Benjamin će baštiniti Gilead."},{"v":20,"t":"A izgnana nekoć vojska sinova Izraelovih baštinit će Kanaan sve do Sarfate; izgnanici jeruzalemski što su u Sefaradu baštinit će gradove negepske."},{"v":21,"t":"Izbavitelji će uzaći na goru Sion da sude gori Ezavljevoj. I tada će nastat' kraljevstvo Jahvino."}]}},"JON":{"1":{"hr":[{"v":1,"t":"Riječ Jahvina dođe Joni, sinu Amitajevu:"},{"v":2,"t":"“Ustani,” reče mu, “idi u Ninivu, grad veliki, i propovijedaj u njemu, jer se zloća njihova popela do mene.”"},{"v":3,"t":"A Jona ustade da pobjegne u Taršiš, daleko od Jahve. Siđe u Jafu i nađe lađu što je plovila u Taršiš. Plati vozarinu i ukrca se da otplovi s njima u Taršiš, daleko od Jahve."},{"v":4,"t":"Ali Jahve podiže na moru silan vjetar i nastade nevrijeme veliko na moru te mišljahu da će se lađa razbiti."},{"v":5,"t":"Uplašiše se mornari; svaki zazva svoga boga, i da bi je olakšali, stadoše iz lađe bacati tovar što bijaše u njoj. Jona pak bijaše sišao na dno lađe, legao i zaspao tvrdim snom."},{"v":6,"t":"Zapovjednik lađe pristupi mu i reče: “Što spavaš kao zaklan? Ustaj i prizivlji Boga svojega! Možda će nas se sjetiti Bog taj da ne poginemo.”"},{"v":7,"t":"Potom rekoše jedni drugima: “Hajde da bacimo ždrijeb da vidimo od koga nam dođe ovo zlo.” Baciše ždrijeb i pade ždrijeb na Jonu."},{"v":8,"t":"Oni mu onda rekoše: “Kaži nam: zbog koga nas ovo zlo snađe, kojim se poslom baviš, odakle dolaziš, iz koje si zemlje i od kojega naroda?”"},{"v":9,"t":"On im odgovori: “Ja sam Hebrej, i štujem Jahvu, Boga nebeskoga, koji stvori more i zemlju.”"},{"v":10,"t":"Ljudi se uplašiše veoma i rekoše mu: “Što si to učinio!” Jer bijahu doznali da on bježi od Jahve - sam im je to pripovjedio."},{"v":11,"t":"Oni ga zapitaše: “Što da učinimo s tobom da nam se more smiri?” Jer se more sve bješnje dizalo."},{"v":12,"t":"On im odgovori: “Uzmite me i bacite u more, pa će vam se more smiriti, jer znam da se zbog mene diglo na vas ovo veliko nevrijeme.”"},{"v":13,"t":"Ljudi uzeše veslati ne bi li se primakli kopnu, jer se more sve bješnje dizalo protiv njih."},{"v":14,"t":"Tad zazvaše Jahvu i rekoše: “Ah, Jahve, ne daj da poginemo zbog života ovoga čovjeka i ne svali na nas krv nevinu, jer ti si Jahve: činiš kako ti je milo.”"},{"v":15,"t":"I uzevši Jonu, baciše ga u more - i more presta bjesnjeti."},{"v":16,"t":"Tada velik strah Jahvin obuze ljude te prinesoše žrtvu Jahvi i učiniše zavjete."}]},"2":{"hr":[{"v":1,"t":"Jahve zapovjedi velikoj ribi da proguta Jonu. Tri dana i tri noći ostade Jona u ribljoj utrobi."},{"v":2,"t":"Iz utrobe riblje stade Jona moliti Jahvu, Boga svojega."},{"v":3,"t":"On reče: “Iz nevolje svoje zavapih Jahvi, i on me usliša; iz utrobe Podzemlja zazvah, i ti si mi čuo glas."},{"v":4,"t":"Ti me baci moru u dubine, i voda me opteče. Sve poplave tvoje i valovi oboriše se na me."},{"v":5,"t":"Pomislih: odbačen sam ispred očiju tvojih. Al' ipak oči upirem svetom Hramu tvojem."},{"v":6,"t":"Vode me do grla okružiše, bezdan me opkoli. Trave mi glavu omotaše,"},{"v":7,"t":"siđoh do korijena planina. Nada mnom se zatvoriše zauvijek zasuni zemljini. Al' ti iz jame izvadi život moj, o Jahve, Bože moj."},{"v":8,"t":"Samo što ne izdahnuh kad se spomenuh Jahve, i molitva se moja k tebi vinula, prema svetom Hramu tvojemu."},{"v":9,"t":"Oni koji štuju isprazna ništavila milost svoju ostavljaju."},{"v":10,"t":"A ja ću ti s pjesmom zahvalnicom žrtvu prinijeti. Što se zavjetovah, ispunit ću. Spasenje je od Gospoda.”"},{"v":11,"t":"Tada Jahve zapovjedi ribi i ona izbljuva Jonu na obalu."}]},"3":{"hr":[{"v":1,"t":"Riječ Jahvina dođe Joni drugi put:"},{"v":2,"t":"“Ustani,” reče mu, “idi u Ninivu, grad veliki, propovijedaj u njemu što ću ti reći.”"},{"v":3,"t":"Jona ustade i ode u Ninivu, kako mu Jahve zapovjedi. Niniva bijaše grad velik do Boga - tri dana hoda."},{"v":4,"t":"Jona prođe gradom dan hoda, propovijedajući: “Još četrdeset dana i Niniva će biti razorena.”"},{"v":5,"t":"Ninivljani povjerovaše Bogu; oglasiše post i obukoše se u kostrijet, svi od najvećega do najmanjega."},{"v":6,"t":"Glas doprije do kralja ninivskoga: on ustade s prijestolja, skide plašt sa sebe, odjenu se u kostrijet i sjede u pepeo."},{"v":7,"t":"Tada se po odredbi kralja i njegovih velikaša oglasi i objavi u Ninivi: “Ljudi i stoka, goveda i ovce da ne okuse ništa, ni da pasu, ni da vodu piju."},{"v":8,"t":"Nego i ljudi i stoka da se pokriju kostrijeću, da glasno Boga zazivlju i da se obrati svatko sa svojega zlog puta i nepravde koju je činio."},{"v":9,"t":"Tko zna, možda će se povratiti Bog, smilovati se i odustati od ljutoga svog gnjeva da ne izginemo?”"},{"v":10,"t":"Bog vidje što su činili: da se obratiše od svojega zlog puta. I sažali se Bog zbog nesreće kojom im bijaše zaprijetio i ne učini."}]},"4":{"hr":[{"v":1,"t":"Joni bi veoma krivo i rasrdi se."},{"v":2,"t":"I ovako se pomoli Jahvi: “Ah, Jahve, nisam li ja to slutio dok još u svojoj zemlji bijah? Zato sam htio prije pobjeći u Taršiš; jer znao sam da si ti Bog milostiv i milosrdan, spor na gnjev i bogat milosrđem i da se nad nesrećom brzo sažališ."},{"v":3,"t":"Sada, Jahve, uzmi moj život, jer mi je bolje umrijeti nego živjeti.”"},{"v":4,"t":"Jahve odgovori: “Srdiš li se ti s pravom?”"},{"v":5,"t":"Jona iziđe iz grada i sjede s istoka gradu; načini ondje kolibu i sjede pod njom u hlad da vidi što će biti od grada."},{"v":6,"t":"A Jahve Bog učini da izraste bršljan nad Jonom i pruži sjenu njegovoj glavi te da ga izliječi od zlovolje. Jona se bršljanu veoma obradova."},{"v":7,"t":"Ali sutradan, u osvit zore, Bog zapovjedi crvu da podgrize bršljan, i on usahnu."},{"v":8,"t":"Kad je ogranulo sunce, posla Bog vruć istočni vjetar; sunce je palilo glavu Joninu te je sasvim klonuo. Poželje umrijeti i reče: “Bolje mi je umrijeti nego živjeti.”"},{"v":9,"t":"Bog upita Jonu: “Srdiš li se s pravom zbog bršljana?” On odgovori: “Da, s pravom sam ljut nasmrt.”"},{"v":10,"t":"Jahve mu reče: “Tebi je žao bršljana oko kojega se nisi trudio, nego je u jednu noć nikao i u jednu noć usahnuo."},{"v":11,"t":"A meni da ne bude žao Ninive, grada velikoga, u kojem ima više od sto i dvadeset tisuća ljudi koji ne znaju razlikovati desno i lijevo, a uz to i mnogo životinja!”"}]}},"MIC":{"1":{"hr":[{"v":1,"t":"Riječ Jahvina, upućena Miheju Morešećaninu u vrijeme Jotama, Ahaza i Ezekije, kraljeva judejskih. Njegova viđenja o Samariji i o Jeruzalemu."},{"v":2,"t":"Čujte, narodi, vi svi! Slušaj, zemljo, i sve što te ispunja! Gospod Jahve protiv vas će svjedočiti - Gospod iz svetoga Hrama svojega!"},{"v":3,"t":"Jer evo: Jahve izlazi iz svetoga mjesta svojega, silazi i hodi po visovima zemaljskim."},{"v":4,"t":"Gore se rastapaju pod njegovim koracima i doline rasijedaju kao vosak pred ognjem, kao voda što se razlijeva niz obronak."},{"v":5,"t":"Sve je to za zločinstvo Jakovljevo i za grijehe doma Izraelova. Koje je zločinstvo Jakovljevo? Nije li Samarija? Što su uzvišice Judine? Nije li Jeruzalem?"},{"v":6,"t":"“Učinit ću od Samarije kamenu gomilu u polju, ledinu za vinograd. Zavaljat ću kamenje njezino u dolinu, otkrit ću joj temelje."},{"v":7,"t":"Razbit će se svi njeni kipovi, sva će joj se plaća bludnička ognjem spaliti, raskomadat ću sve njene idole, jer su od bludničke plaće nakupljeni, i opet će postati plaćom bludničkom.”"},{"v":8,"t":"“Zato ću zakukati i zaridati, ići ću gol i bos, zavijat ću kao šakali, urlikat ću kao nojevi."},{"v":9,"t":"Jer njenoj rani nema lijeka, sve do Jude dopire, dotiče Vrata moga naroda, sve do Jeruzalema!"},{"v":10,"t":"Ne objavljujte toga u Gatu, u Akonu nemojte plakati! U Bet Leafri valjajte se u prašini!"},{"v":11,"t":"Odlazi sramotno, stanovnice šafirska! Iz svoga grada nije izašla stanovnica saananska! Bet Haesel iščupan je iz temelja, iz svojih čvrstih osnova."},{"v":12,"t":"Kako se može nadati sreći stanovnica marotska? Jer nesreća silazi od Jahve sve do vrata jeruzalemskih."},{"v":13,"t":"Upregni brze konje u bojna kola, stanovnice lakiška! To je bio početak grijeha Kćeri sionske, jer su se u tebi našla zločinstva Izraelova."},{"v":14,"t":"Zato ćeš dati otpusnicu Morešet Gatu, domovi će akzipski razočarati kraljeve izraelske."},{"v":15,"t":"Još ću ti dovesti osvajača, stanovnice mareška, stići će do Adulama slava Izraelova."},{"v":16,"t":"Čupaj kosu i ostriži se za milom djecom svojom! Postani ćelava kao orao lešinar, jer su izgnana daleko od tebe.”"}]},"2":{"hr":[{"v":1,"t":"Teško onima koji smišljaju nedjelo i snuju zlo na posteljama svojim! Kad svane dan, oni ga izvrše, jer je sila u njihovoj ruci."},{"v":2,"t":"Zažele li polja, otimaju ih, i kuće, uzimaju ih; čine nasilje čovjeku i kući njegovoj, vlasniku i posjedu njegovu."},{"v":3,"t":"Zato ovako govori Jahve: “Evo tome rodu smišljam zlo iz kojega nećete izvući vratova, niti ćete hoditi ponosito, jer će biti zlo vrijeme."},{"v":4,"t":"U onaj će vam se dan složiti rugalica, zapjevati tužaljka i reći: 'Propalo je! Posve smo opustošeni, baština je naroda moga otuđena i nitko da mu je vrati, naša polja podijeljena su odmetniku.'"},{"v":5,"t":"Zato neće biti nikoga tko bi bacio kocku za dio tvoj u zboru Jahvinu.”"},{"v":6,"t":"“Ne balite!” - bale oni - “Tako se ne bali! Sramota na nas neće pasti!"},{"v":7,"t":"Zar će biti proklet dom Jakovljev? Zar je Jahve izgubio strpljivost? Zar on tako postupa? Nisu li riječi njegove ugodne Izraelu, narodu njegovu?”"},{"v":8,"t":"Vi se sami dižete kao neprijatelji narodu mojemu. Čovjeku nezazornu vi otimate kabanicu, onome koji bez straha putuje ratne strahote dosuđujete."},{"v":9,"t":"Vi izgonite žene moga naroda iz njihovih milih domova; djeci njihovoj zauvijek oduzimate slavu koju sam im dao:"},{"v":10,"t":"“Ustanite, idite! Ovo nije počivalište! Zbog nečistoće teško vas uže svezalo.”"},{"v":11,"t":"Kad bi mogao biti nadahnut čovjek koji izmišlja ovu opsjenu: “Prorokujem ti vino i piće”, on bi bio prorok narodu ovome."},{"v":12,"t":"Svega ću te sabrati, Jakove, sakupit ću Ostatak Izraelov! Smjestit ću ih zajedno kao ovce u toru, kao stado na paši - neće se bojati nikoga."},{"v":13,"t":"Pred njima stupa rušilac: oni će se porušiti i ući, kroz vrata će proći i izaći; pred njima će ići njihov kralj, Jahve će biti na čelu."}]},"3":{"hr":[{"v":1,"t":"Potom rekoh: “Čujte sada, glavari kuće Jakovljeve, suci doma Izraelova! Nije li na vama da znate što je pravo? Ali vi mrzite dobro, a ljubite zlo!"},{"v":2,"t":"Vi ljudima derete kožu s tijela i meso s kosti njihovih."},{"v":3,"t":"Oni proždiru tijelo moga naroda i deru mu kožu, lome kosti. Oni ih komadaju kao u loncu, kao meso u punom kotlu!"},{"v":4,"t":"Zato, oni će Jahvu zazivati, a on im neće odgovoriti. Sakrit će, u ono vrijeme, lice od njih zbog zločina koje su počinili.”"},{"v":5,"t":"Ovako govori Jahve protiv prorokÄa koji moj narod zavode: “Ako imaju zalogaj u zubima, proglašuju: 'Mir!' Ali protiv onoga koji im ništa ne stavlja u usta naviještaju sveti rat."},{"v":6,"t":"Zato ćete imati noć mjesto vaših viđenja i tminu mjesto proricanja. Zaći će sunce tim prorocima i dan će za njih pomrčati."},{"v":7,"t":"Tada će se posramiti vidovnjaci i zblaniti vračari. Svi će oni pokriti gubice, jer odgovora Božjeg neće biti."},{"v":8,"t":"Ali ja sam pun snage i duha Jahvina, pun pravde i jakosti da objavim Jakovu opačinu njegovu, Izraelu njegov grijeh."},{"v":9,"t":"Čujte dakle ovo, glavari kuće Jakovljeve, suci doma Izraelova, vi kojima se pravda gadi te izvrćete sve što je ispravno!"},{"v":10,"t":"Vi koji gradite Sion u krvi i Jeruzalem u zločinu!"},{"v":11,"t":"Glavari njegovi sude prema mitu, svećenici njegovi poučavaju radi zarade, proroci njegovi bale za novac. A na Jahvu se oni pozivaju i govore: 'Nije li Jahve u našoj sredini? Neće na nas zlo navaliti.'"},{"v":12,"t":"Poradi vas i vaše krivnje Sion će biti polje preorano, Jeruzalem ruševina, a Goru Doma prekrit će šuma.”"}]},"4":{"hr":[{"v":1,"t":"Dogodit će se na kraju danÄa: Gora Doma Jahvina bit će postavljena vrh svih gora, uzvišena iznad svih bregova."},{"v":2,"t":"K njoj će se stjecat svi narodi, nagrnut će mnoga plemena i reći: “Hajde, uziđimo na goru Jahvinu, u Dom Boga Jakovljeva! On će nas naučit' svojim putovima, i hodit ćemo stazama njegovim. Jer će sa Siona Zakon izaći, riječ Jahvina iz Jeruzalema.”"},{"v":3,"t":"On će upravljati mnogim pučanstvima i bit će sudac moćnim narodima. Svoje će mačeve prekovati u ralice, a svoja koplja u radne srpove. Narod na narod neće mača dizati niti će se više za rat vježbati."},{"v":4,"t":"Svaki će mirno živjeti pod lozom vinovom, pod smokvom svojom, i nitko ga neće plašiti. To rekoše usta Jahve nad Vojskama."},{"v":5,"t":"Jer svi narodi idu, svaki u ime boga svojega, a mi, mi idemo u imenu Jahve, Boga našega, uvijek i dovijeka."},{"v":6,"t":"“U onaj dan - riječ je Jahvina - sabrat ću hrome, okupiti raspršene i sve kojima sam zlo učinio."},{"v":7,"t":"Od hromih ću Ostatak učiniti, moćan narod od onih što su izgnani.” Tada će Jahve nad njima kraljevati na gori Sionu od sada i dovijeka."},{"v":8,"t":"I ti Kulo stadÄa, Ofele Kćeri sionske, opet će se tebi vratiti prijašnja vlast, kraljevstvo Kćeri jeruzalemske."},{"v":9,"t":"Zašto sada kukaš kuknjavom? Nema li kralja u tebi? Zar su savjetnici tvoji propali da te obuzimlju bolovi kao porodilju?"},{"v":10,"t":"Savijaj se od boli i kriči, Kćeri sionska, kao žena koja porađa, jer ćeš sada iz grada izići i stanovati na polju. Do Babilona ti ćeš otići, ondje ćeš se osloboditi, ondje će te Jahve otkupiti iz šaka tvojih dušmana."},{"v":11,"t":"A sada se mnogi narodi protivu tebe sabraše. Oni govore: “Neka se obeščasti, neka se naše oči nasite Siona!”"},{"v":12,"t":"Ali zamisli Jahvine oni ne znaju i ne razumiju namjere njegove: kao snoplje na gumnu on ih je sabrao."},{"v":13,"t":"Ustani! Ovrši žito, Kćeri sionska, jer ti pravim gvozden rog i mjedena kopita. I satrt ćeš mnoge narode; zavjetovat ćeš Jahvi blago njihovo i bogatstvo njihovo Gospodaru sve zemlje."},{"v":14,"t":"Utvrdi se sada, Tvrđavo! Opkoljeni smo i opsjednuti, palicom po licu udaraju Suca Izraelova."}]},"5":{"hr":[{"v":1,"t":"A ti, Betleheme Efrato, najmanji među kneževstvima Judinim, iz tebe će mi izaći onaj koji će vladati Izraelom; njegov je iskon od davnina, od vječnih vremena."},{"v":2,"t":"Zato će ih Jahve ostaviti dok ne rodi ona koja ima roditi. Tada će se Ostatak njegove braće vratiti djeci Izraelovoj."},{"v":3,"t":"On će se uspraviti, na pašu izvodit' svoje stado silom Jahvinom, veličanstvom imena Boga svojega. Oni će u miru živjeti, jer će on rasprostrijeti svoju vlast sve do krajeva zemaljskih."},{"v":4,"t":"On - on je mir! Ako Asirci provale u našu zemlju, ako stupe u naše dvore, podići ćemo na njih sedam pastira, osam narodnih knezova."},{"v":5,"t":"Zemlju asirsku oni će mačem opasti, zemlju Nimrodovu sabljama. I on će nas osloboditi od Asiraca ako provale u našu zemlju, ako stupe na naše tlo."},{"v":6,"t":"Tada će Ostatak Jakovljev, među brojnim narodima, biti kao rosa koja od Jahve dolazi, kao kapljice kiše na travi koja ne čeka na čovjeka niti iščekuje sina čovječjeg."},{"v":7,"t":"Tada će Ostatak Jakovljev, među brojnim narodima, biti kao lav među šumskim zvijerima, kao lavić među ovčjim stadima: svaki put kad prolazi, on gazi nogama, razdire, i nitko da od njega izbavi."},{"v":8,"t":"Tvoja ruka neka se podigne na protivnike, svi tvoji neprijatelji bit će zatrti!"},{"v":9,"t":"“U onaj dan - riječ je Jahvina - potamanit ću sve tvoje konje, uništiti tvoja bojna kola;"},{"v":10,"t":"razorit ću po tvojoj zemlji svako naselje, porušiti sve tvoje tvrde gradove."},{"v":11,"t":"Zatrt ću iz tvoje ruke bajanje, vračara više nećeš imati;"},{"v":12,"t":"i zatrt ću u tebi sve kipove i stupove kamene. I ti se više nećeš klanjati pred djelom ruku svojih."},{"v":13,"t":"Iskorijenit ću ašere iz tebe i razorit ću tvoje gradove."},{"v":14,"t":"U gnjevu, u bijesu, izvršit ću osvetu na narodima koji nisu slušali.”"}]},"6":{"hr":[{"v":1,"t":"Čujte, dakle, riječ koju govori Jahve: “Ustani! Povedi parnicu pred gorama, i neka bregovi čuju tvoj glas!”"},{"v":2,"t":"Slušajte, gore, parnicu Jahvinu, čujte, temelji zemaljski, jer Jahve se parbi s narodom svojim, on se parniči s Izraelom:"},{"v":3,"t":"“Narode moj, što sam ti učinio? Čime sam te zamorio? Odgovori mi."},{"v":4,"t":"Ja sam tebe izveo iz zemlje egipatske, izbavio te iz kuće ropstva; poslao sam pred tobom Mojsija, Arona i Mirjamu."},{"v":5,"t":"Narode moj, sjeti se sada: Što je bio naumio Balak, kralj moapski? Što je njemu odgovorio Bileam, sin Beorov? ...od Šitima do Gilgala, da poznaš pravedna djela Jahvina.”"},{"v":6,"t":"“S čime ću doći pred Jahvu, hoću li pasti ničice pred Bogom Svevišnjim? Hoću li doći preda nj sa žrtvom paljenicom, s teocima od jedne godine?"},{"v":7,"t":"Hoće li mu biti mile tisuće ovnova, tisuće tisuća potokÄa ulja? Treba li prinijeti sina prvorođenog zbog svoga zločina, plod svoje utrobe zbog grijeha koji sam počinio?”"},{"v":8,"t":"“Objavljeno ti je, čovječe, što je dobro, što Jahve traži od tebe: samo činiti pravicu, milosrđe ljubiti i smjerno sa svojim Bogom hoditi.”"},{"v":9,"t":"Jahvin glas viče gradu: “Slušajte, vi plemenjaci i sabore gradski!"},{"v":10,"t":"Zar mogu podnositi krivo stečeno blago i patvorenu efu prokletu?"},{"v":11,"t":"Mogu li opravdati onoga koji se služi mjerom krivom, vrećom krivotvorenih utega?"},{"v":12,"t":"Bogataši vaši puni su okrutnosti, stanovnici vaši laž govore, varljiv je jezik u njihovim ustima!"},{"v":13,"t":"Zato sam te i ja počeo udarati, tamaniti zbog grijeha tvojih."},{"v":14,"t":"Jest ćeš, a nećeš se nasititi, gladan ćeš ostati; stavljat ćeš na stranu, a ništa nećeš sačuvati; ako što i sačuvaš, ja ću maču predati."},{"v":15,"t":"Sijat ćeš, ali nećeš žeti; tijestit ćeš maslinu, a ulja neće biti; gazit ćeš mošt, a vina nećeš piti."},{"v":16,"t":"Držiš se zakona Omrijevih i svih djela doma Ahabova, živiš po osnovama njihovim: učinit ću od tebe pustinju, od žitelja tvojih porugu, da nosite sramotu mnogih naroda.”"}]},"7":{"hr":[{"v":1,"t":"Teško meni! Postao sam kao žetelac ljeti, kao trgač poslije jematve: nema bobice grožđa da je pozobljem, nema smokve ranke za kojom žudim!"},{"v":2,"t":"Vjernici su iščezli iz zemlje: nijednog pravednika među ljudima! Svi vrebaju za krvoprolićem, svaki svome bratu mrežu postavlja."},{"v":3,"t":"Njihove ruke za zlo su sposobne: glavar traži dar, sudac sudi prema poklonu, velikaš po svome hiru odlučuje."},{"v":4,"t":"I najbolji među njima je kao trn, najpravedniji kao drača živica. Iskušenje njihovo danas sa Sjevera dolazi, dolazi ura strave njihove."},{"v":5,"t":"Ne pouzdavajte se u bližnjega, ne vjerujte u prijatelja; pred onom koja s tobom dijeli postelju pazi da usta ne otvoriš."},{"v":6,"t":"Jer sin svoga oca zlostavlja, kćerka na majku ustaje, snaha na svoju svekrvu, svakome je dušmanin njegov ukućanin."},{"v":7,"t":"A ja, prema Jahvi ja sam zagledan, čekam na Boga koji spasava, Bog moj mene će uslišati."},{"v":8,"t":"Ne raduj se mome zlu, dušmanko moja, ako sam pao, ustat ću; ako boravim u tminama, Jahve je svjetlost moja."},{"v":9,"t":"Moram podnositi srdžbu Jahvinu, jer sam protiv njega sagriješio, sve dok on ne prosudi spor moj i izrekne pravdu; izvest će me na svjetlost, gledat ću pravednost njegovu."},{"v":10,"t":"Kada ga moja dušmanka ugleda, od stida će se pokriti ona koja mi je govorila: “Gdje je on, Jahve, tvoj Bog?” Moje će se oči naslađivati kad je ugledam: ona će biti zgažena kao blato na putu."},{"v":11,"t":"Dolazi dan kad će se sazidati tvoji bedemi! Toga dana nadaleko će se prostirati tvoje granice!"},{"v":12,"t":"Toga dana dolazit će k tebi od zemlje asirske do Egipta, od Tira do Rijeke, od mora do mora, od gore do gore."},{"v":13,"t":"Zemlja će postat' pustinja zbog stanovnika svojih, zbog djela njihovih."},{"v":14,"t":"Pasi svoj narod svojom palicom, stado svoje baštine, koje osamljeno živi u šikarju, usred plodnih voćnjaka. Neka pase u Bašanu i Gileadu, kao u davne dane!"},{"v":15,"t":"Kao u dane kad si izašao iz Egipta, pokaži nam čudesa!"},{"v":16,"t":"Narodi će ih vidjeti i bit će posramljeni uza svu silu svoju; stavit će ruku na usta i uši će im oglušiti."},{"v":17,"t":"Lizat će prašinu kao zmija, kao gmazovi koji gmižu po zemlji. Izići će dršćući iz svojih jazbina, prestravljeni i ustrašeni pred tobom."},{"v":18,"t":"Tko je Bog kao ti koji prašta krivnju, koji grijeh oprašta i prelazi preko prekršaja Ostatka baštine svoje, koji ne ustraje dovijeka u svome gnjevu, nego uživa u pomilovanju?"},{"v":19,"t":"Još jednom, imaj milosti za nas! Satri naše opačine, baci na dno mora sve grijehe naše!"},{"v":20,"t":"Udijeli Jakovu vjernost svoju, dobrotu svoju Abrahamu, kako si se zakleo ocima našim od dana iskonskih."}]}},"NAM":{"1":{"hr":[{"v":1,"t":"Proročanstvo nad Ninivom. Knjiga viđenja Nahuma Elkošanina."},{"v":2,"t":"Jahve je Bog ljubomoran i osvetnik! Jahve se osvećuje, gospodar srdžbe! Jahve se osvećuje svojim protivnicima, ustrajan u gnjevu na neprijatelje."},{"v":3,"t":"Jahve je spor u gnjevu, ali silan u moći. Ne, Jahve neće pustiti krivca nekažnjena. U vihoru i oluji put je njegov, oblaci su prašina koju podižu njegovi koraci."},{"v":4,"t":"Prijeti moru i isušuje ga, presušuje sve rijeke. ...Bašan i Karmel uvenuli su, povenuli su pupoljci Libana!"},{"v":5,"t":"Pred njim se gore potresaju, bregovi se ljuljaju, zemlja se pod njim provaljuje, krug zemaljski i sve što na njem stanuje."},{"v":6,"t":"Tko može izdržati pred bijesom njegovim? Tko će odoljeti pred gnjevnom srdžbom njegovom? Jarost se njegova kao vatra izlijeva i litice se pred njim kidaju."},{"v":7,"t":"Jahve je dobar onima koji se u njeg' uzdaju, on je okrilje u dan nevolje, poznaje one koji se njemu utječu"},{"v":8,"t":"kada potopne vode poplave. Uništit će one koji se protiv njega podižu, progonit će svoje dušmane u najmrkliji mrak."},{"v":9,"t":"Što vi snujete protiv Jahve? On uništava do kraja; nevolja se neće dva puta podići."},{"v":10,"t":"Kao trnovita šikara i kao pijanci na pijanki, k'o suha slama bit će potpuno smlavljeni."},{"v":11,"t":"Iz tebe je potekao onaj koji snuje zlo protiv Jahve, savjetnik Belijala."},{"v":12,"t":"Jahve ovako govori: “Neka su spremni, neka mnogobrojni, bit će pokošeni, uništeni. Ako sam te ponizio, neću te odsada ponižavati."},{"v":13,"t":"A sada, razbit ću jaram koji te steže, raskidat ću tvoje okove.”"},{"v":14,"t":"Protiv tebe Jahve naređuje: “Neće više biti roda tvoga imena, iz hrama tvojih bogova istrijebit ću likove rezane i livene, a od tvog groba ruglo ću učiniti.”"}]},"2":{"hr":[{"v":1,"t":"Gledajte, preko gora hrli glasnik, on naviješta: “Spasenje!” Svetkuj svoje blagdane, Judo, ispuni svoje zavjete, jer Belijal više neće prolaziti po tebi, on je sasvim zatrt."},{"v":2,"t":"Protiv tebe dolazi rušitelj. Postavi stražu na bedeme, gledaj na put, opaši bedra, saberi sve svoje snage."},{"v":3,"t":"Da, Jahve će obnoviti vinograd Jakovljev i vinograd Izraelov. Pljačkaši ih opljačkali, mladice im potrli."},{"v":4,"t":"Štitovi njegovih junaka crvene se, njegovi su ratnici u grimizu; ognjem blista čelik na njihovim bojnim kolima kad krenu u boj; konji im se propinju."},{"v":5,"t":"Po ulicama bjesne bojna kola, lete preko trgova; na pogled su baklje goruće; kao munje, samo sijevaju."},{"v":6,"t":"Pozivaju se borci odabrani, bacaju se u rovove, hrle brzo na bedeme, već je zaklon postavljen."},{"v":7,"t":"Vrata koja gledaju na Rijeku otvaraju se, strava je u palači."},{"v":8,"t":"Podižu, u izgnanstvo odvode Gospodaricu, robinjice njene cvile, tuguju kao golubice, u prsa se udaraju."},{"v":9,"t":"Niniva je nabujalo jezero, oni bježe pred vodom njezinom. “Zaustavite se, stanite!” Ali se nitko ne okreće."},{"v":10,"t":"“Grabite srebro! Grabite zlato!” Blagu kraja nema, obilje dragocjenosti!"},{"v":11,"t":"Pljačkanje, haranje, razaranje! Srce zamire, koljena klecaju, u bedrima drhtavica, svima su lica poblijedjela."},{"v":12,"t":"Gdje je skrovište lavovima i log lavićima? Kad je lav izlazio, lavica je ostajala i lavovi mališani; plašio ih nitko nije."},{"v":13,"t":"Lav je grabio za svoje laviće, davio je za svoje lavice; svoje spilje punio je plijenom, svoja skrovišta lovinom."},{"v":14,"t":"“Evo me! Tebi!” - riječ je Jahve nad Vojskama. “Pretvorit ću u dim tvoja bojna kola, mač će poklati tvoje laviće. Istrijebit ću sa zemlje tvoja pljačkanja, i neće se više čuti povik tvojih glasnika.”"}]},"3":{"hr":[{"v":1,"t":"Teško gradu krvničkom, pun je laži, prepun grabeža, s pljačkanjem on ne prestaje!"},{"v":2,"t":"Slušajte! Pucaju bičem! Slušajte! Štropot točkova! Konji upropanj, kola poskakuju."},{"v":3,"t":"Konjanici u stremenu, mačevi sjaju, koplja sijevaju ... gomile ranjenih, snopovi mrtvih, trupla unedogled, svuda se o truplo spotiče!"},{"v":4,"t":"Eto plaće za razvrat bludnice, ljupke ljubaznice, vješte čarobnice koja je zavodila narode svojim razvratom i plemena svojim čaranjima."},{"v":5,"t":"“Evo me! Tebi!” - riječ je Jahve nad Vojskama. “Na tvoje lice podignut ću skute tvoje haljine, tvoju golotinju pokazat ću narodima, tvoju sramotu kraljevstvima."},{"v":6,"t":"Bacit ću na tebe smeće, osramotit ću te, izložiti na stup sramote."},{"v":7,"t":"Svaki koji te vidi, bježat će od tebe. Reći će: 'Niniva! Kakva razvalina!' Tko je može požaliti? Gdje joj naći tješitelje?”"},{"v":8,"t":"Jesi li tvrđa od Tebe Amonove koja sjedi na rukavima Rijeke? Njezino predziđe bilo je more, njezini bedemi bile su vode."},{"v":9,"t":"Njezina snaga bila je Etiopija, Egipat; nije imala granica. Narodi Puta i Libije bili su joj pomoćnici."},{"v":10,"t":"A i ona je otišla u progonstvo, morala je ići u sužanjstvo; njezina nejaka djeca bila su razmrskana po svim raskršćima; za ugledne ljude njezine bacali su ždrijeb, svi njezini velikani okovani su lancima."},{"v":11,"t":"Tako ćeš i ti biti slomljena, bit ćeš svladana; tako ćeš i ti morati tražiti utočište pred dušmaninom."},{"v":12,"t":"Tvoje utvrde sve su kao smokvino stablo s urodom mladih smokava; kad se potrese stablo, smokve padaju u usta svakome koji ih želi jesti."},{"v":13,"t":"Gledaj svoj narod: sve je žensko u domu tvome; vrata tvoje zemlje širom se otvaraju neprijatelju; oganj je sažgao tvoje prijevornice."},{"v":14,"t":"Nacrpi vode za opsadu, utvrdi svoje bedeme, gnječi blato, gazi ilovaču, uzmi kalup za opeku."},{"v":15,"t":"A ipak će te oganj sažeći i mač potamaniti. Namnoži se kao kukci, namnoži se kao skakavci;"},{"v":16,"t":"[16a] umnoži svoje trgovce da ih bude više nego zvijezda na nebu,"},{"v":17,"t":"[17a] tvoje posade neka bude kao skakavaca, a tvojih pisara kao kobilica. Borave po zidovima kad je hladan dan. Sunce grane: [16b] kukci razvijaju krilašca i lete, [17b] i odlaze tko zna kamo."},{"v":18,"t":"Jao! Kako su zaspali tvoji pastiri, kralju asirski? Tvoji izabrani vojnici drijemaju, narod se tvoj raspršio po gorama, nitko ga više ne može sakupiti."},{"v":19,"t":"Tvojoj rani nema lijeka! Neizlječiva je tvoja ozljeda. Svi koji to saznaju plješću tvojoj razvalini. Tko nije bez sanka i prestanka osjećao na sebi tvoju okrutnost?"}]}},"HAB":{"1":{"hr":[{"v":1,"t":"Proroštvo koje vidje prorok Habakuk."},{"v":2,"t":"Dokle ću, Jahve, zapomagati, a da ti ne čuješ? Vikati k tebi “Nasilje!” a da ti ne spasiš?"},{"v":3,"t":"Zašto mi nepravdu iznosiš pred oči, zašto gledaš ugnjetavanje? Pljačka je i nasilje preda mnom. Raspra je, razmirica bjesni!"},{"v":4,"t":"Zakon je izgubio snagu, a pravda se ni načas ne pomalja. Da, zlikovac progoni pravednika, pravo je stoga izopačeno."},{"v":5,"t":"Obazrite se na narode, pogledajte, čudite se, zapanjite! Jer u vaše dane činim djelo u koje ne biste vjerovali da vam ga tko ispriča."},{"v":6,"t":"Da! Evo dižem Kaldejce, narod divlji i naprasit što nadire širom zemlje da obitavališta otme tuđa."},{"v":7,"t":"On je strašan i jezovit, od njega samog izlazi njegovo pravo i njegov ponos."},{"v":8,"t":"Konji su mu brži od leoparda, hitriji od vukova uvečer; jahači mu poskakuju, stižu izdaleka, ustremljeni k'o orlovi da plijen proždru."},{"v":9,"t":"Svi će doći rad' grabeža, lica im žegu k'o istočni vjetar, grabe roblje kao pijesak!"},{"v":10,"t":"Taj se narod kraljevima ruga, podsmjehuje knezovima, poigrava se svim utvrdama, nasipa zemlju i zauzima ih."},{"v":11,"t":"Tad se k'o vjetar okrenu i ode, zlikovac komu je snaga bog postala."},{"v":12,"t":"Nisi li od davnih vremena, Jahve, Bože moj, Sveče moj? Ti koji ne umireš! Ti si, Jahve podigao ovaj narod radi pravde, postavio ga, Stijeno, da kažnjava."},{"v":13,"t":"Prečiste su tvoje oči da bi zloću gledale. Ti ne možeš motriti tlačenja. Zašto gledaš vjerolomce, šutiš kad zlikovac ništi pravednijeg od sebe?"},{"v":14,"t":"Postupaš s ljudima k'o s morskim ribama, k'o s gmazovima što nemaju gospodara!"},{"v":15,"t":"On ih sve lovi na udicu, izvlači ih mrežom, pređom ih skuplja i tako se raduje i likuje."},{"v":16,"t":"Stog žrtvuje mreži svojoj, pali tamjan svojoj pređi jer mu pribavljaju zalogaj slastan, hranu pretilu."},{"v":17,"t":"Valja li, dakle, da neprestano poteže mač i kolje narod nemilice?"}]},"2":{"hr":[{"v":1,"t":"Stat ću na stražu svoju, postavit se na bedem, paziti što će mi reći, kako odgovorit na moje tužbe."},{"v":2,"t":"Tada Jahve odgovori i reče: “Zapiši viđenje, ureži ga na pločice, da ga čitač lako čita.”"},{"v":3,"t":"Jer ovo je viđenje samo za svoje vrijeme: ispunjenju teži, ne vara; ako stiže polako, čekaj, jer odista će doći i neće zakasniti!"},{"v":4,"t":"Gle: propada onaj čija duša nije pravedna, a pravednik živi od svoje vjere."},{"v":5,"t":"Bogatstvo je odista podmuklo! Ohol je i ne može počinuti tko ždrijelo razvaljuje k'o Podzemlje, tko je kao smrt nezasitan, tko sabire za se sve narode, tko kupi za se sva plemena!"},{"v":6,"t":"Zar mu se neće svi podrugivati, rugalicu i zagonetku spjevat' protiv njega? Reći će: Jao onom tko množi što nije njegovo (a dokle će?) i opterećuje se zalogama!"},{"v":7,"t":"Neće li naglo ustat' vjerovnici tvoji, neće li se probuditi ljuti tvoji tlačitelji? Tada ćeš im plijen biti!"},{"v":8,"t":"Jer si opljačkao mnoge narode, sav ostatak naroda opljačkat će tebe, jer si prolio krv ljudsku, poharao zemlju, grad i sve mu žitelje."},{"v":9,"t":"Jao onom tko otimačinu zgrće nepravednu kući svojoj, da visoko svije gnijezdo svoje i otkloni ruku zla!"},{"v":10,"t":"Nanese sramotu kući svojoj: zatirući mnoga plemena, griješiš protiv sebe."},{"v":11,"t":"Jer iz samih zidova kamen kriči, a krovna mu greda odgovara."},{"v":12,"t":"Jao onom tko grad diže krvlju i tvrđavu zasnuje na nepravdi!"},{"v":13,"t":"Nije li to, gle, od Jahve nad Vojskama da se narodi za oganj trude, puci nizašto muče?"},{"v":14,"t":"Jer će se zemlja napuniti znanja o slavi Jahvinoj kao što vode prekrivaju more."},{"v":15,"t":"Jao onom tko bližnjeg navodi na piće, ulijeva otrov dok on pije da bi promatrao njegovu nagost!"},{"v":16,"t":"Ti si pijan od sramote, ne od slave! Pij samo i pokazuj kapicu. Dolazi ti pehar iz desnice Jahvine i sramota na slavu tvoju!"},{"v":17,"t":"Nasilje nad Libanonom tebe će prestraviti, pokolj zvijeri, jer si ljudsku krv prolio, poharao zemlju, grad i njegove žitelje."},{"v":18,"t":"Čemu koristi tesan lik da ga umjetnik teše? Čemu lijevan lik, lažno proroštvo, da se tvorac njegov u nj pouzdaje oblikujuć' nijeme kipove?"},{"v":19,"t":"Jao onom tko komadu drva kaže: “Probudi se!” Kamenu nijemom: “Preni se!” On da prorokuje? Optočen može biti i zlatom i srebrom, ali nikakva daha životnog nema u njemu."},{"v":20,"t":"Ali je Jahve u svojem svetom Hramu: nek' zemlja sva zašuti pred njime!"}]},"3":{"hr":[{"v":1,"t":"Molitva. Od proroka Habakuka. Na način tužbalice."},{"v":2,"t":"Jahve, čuo sam za slavu tvoju, Jahve, tvoje mi djelo ulijeva jezu! Ponovi ga u naše vrijeme! Otkrij ga u naše vrijeme! U gnjevu se svojem smilovanja sjeti!"},{"v":3,"t":"Bog stiže iz Temana, a Svetac s planine Parana! Veličanstvo njegovo zastire nebesa, zemlja mu je puna slave."},{"v":4,"t":"Sjaj mu je k'o svjetlost, zrake sijevaju iz njegovih ruku, ondje mu se krije sila."},{"v":5,"t":"Kuga pred njim ide, groznica ga sustopice prati."},{"v":6,"t":"On stane, i zemlja se trese, on pogleda, i dršću narodi. Tad se raspadoše vječne planine, bregovi stari propadoše, njegove su staze od vječnosti."},{"v":7,"t":"Prestrašene vidjeh kušanske šatore, čadore što dršću u zemlji midjanskoj."},{"v":8,"t":"Jahve, planu li tvoj gnjev na rijeke ili jarost tvoja na more te jezdiš na svojim konjima, na pobjedničkim bojnim kolima?"},{"v":9,"t":"Otkrivaš svoj luk i otrovnim ga strijelama sitiš. Bujicama rasijecaš tlo,"},{"v":10,"t":"planine dršću kad te vide, navaljuje oblaka prolom, bezdan diže svoj glas."},{"v":11,"t":"Sunce uvis diže ruke, mjesec u obitavalištu svojem popostaje, pred blijeskom tvojih strijela, pred blistavim sjajem koplja tvoga."},{"v":12,"t":"Jarosno po zemlji koračaš, srdito gaziš narode."},{"v":13,"t":"Iziđe da spasiš narod svoj, da spasiš svog pomazanika; sori vrh kuće bezbožnikove, ogoli joj temelje do stijene."},{"v":14,"t":"Kopljima si izbo vođu ratnika njegovih, koji navališe da nas s radošću satru, kao da će potajice proždrijet' ubogoga."},{"v":15,"t":"Gaziš po moru s konjima svojim, po pučini silnih voda!"},{"v":16,"t":"Čuo sam! Sva se moja utroba trese, podrhtavaju mi usne na taj zvuk, trulež prodire u kosti moje, noge klecaju poda mnom. Počinut ću kada dan tjeskobni svane narodu što nas sad napada."},{"v":17,"t":"Jer smokvino drvo neće više cvasti niti će na lozi biti ploda, maslina će uskratiti rod, polja neće donijeti hrane, ovaca će nestati iz tora, u oborima neće biti ni goveda."},{"v":18,"t":"Ali ja ću se radovati u Jahvi i kliktat ću u Bogu, svojem Spasitelju."},{"v":19,"t":"Jahve, moj Gospod, moja je snaga, on mi daje noge poput košutinih i vodi me na visine. Zborovođi. Na žičanim glazbalima."}]}},"ZEP":{"1":{"hr":[{"v":1,"t":"Riječ Jahvina upućena Sefaniji, sinu Kušija, sina Gedalijina, sina Amarjina, sina Ezekijina, u vrijeme Jošije, sina Amonova, kralja judejskoga."},{"v":2,"t":"“Da, sve ću zbrisati s lica zemlje” - riječ je Jahvina!"},{"v":3,"t":"“Izbrisat ću ljude i zvijeri, ptice nebeske i ribe morske, učinit ću da padnu bezbožnici, istrijebit ću ljude s lica zemlje” - riječ je Jahvina!"},{"v":4,"t":"“Podignut ću ruku na Judu i na sve stanovnike Jeruzalema i istrijebit ću iz ovoga mjesta ostatak Baalov, ime služitelja idolskih sa svećenicima njegovim;"},{"v":5,"t":"one koji se klanjaju na krovovima vojsci nebeskoj, one koji se klanjaju pred Jahvom a zaklinju se Milkomom;"},{"v":6,"t":"one koji su se odmetnuli od Jahve, koji ne traže Jahvu i nimalo za nj ne mare.”"},{"v":7,"t":"Tišina pred Jahvom Gospodom, jer je dan Jahvin blizu! Da, Jahve je prigotovio žrtvu, posvetio je svoje uzvanike."},{"v":8,"t":"“U dan žrtve Jahvine, kaznit ću knezove, sinove kraljeve, i sve koji se oblače na način tuđinski."},{"v":9,"t":"Kaznit ću u taj dan sve koji preko praga poskakuju, koji Dom Gospodara svojega pune nasiljem i prijevarom.”"},{"v":10,"t":"“U onaj dan” - riječ je Jahvina - “vapaj će se podići od Ribljih vrata, urlici iz novog dijela grada, silna lomljavina sa brežuljaka."},{"v":11,"t":"Kukajte, stanovnici makteški, jer je satrt sav narod kanaanski, zbrisani su svi mjerači srebra."},{"v":12,"t":"I u to vrijeme pretražit ću Jeruzalem sa zubljama i pohodit ću kaznom ljude koji miruju na svojoj vinskoj droždini i u svom srcu govore: 'Jahve ne može učiniti ni dobro ni zlo.'”"},{"v":13,"t":"Blago njihovo bit će prepušteno pljački, njihove kuće pustošenju. Oni su gradili kuće - neće u njima stanovati; sadili su vinograde - iz njih vina neće piti."},{"v":14,"t":"Blizu je dan Jahvin, veliki! Blizu je i žurno dolazi! Gorak je glas dana Jahvina: tada će i junak zajaukati."},{"v":15,"t":"Dan gnjeva, onaj dan! Dan tjeskobe i nevolje! Dan užasa i pustošenja! Dan pomrčine i naoblake! Dan tmina i magluština!"},{"v":16,"t":"Dan trubljavine i bojne vike na gradove utvrđene i na visoka kruništa."},{"v":17,"t":"“Prepustit ću ljude nevoljama i vrludat će kao slijepci (jer su protiv Jahve sagriješili), krv će se njihova prosuti kao prašina, njihova trupla bit će bačena kao smeće."},{"v":18,"t":"Ni njihovo srebro ni njihovo zlato neće ih spasiti.” U dan gnjeva Jahvina oganj njegove revnosti svu će zemlju sažeći. Jer on će uništiti, zatrti sve stanovnike zemlje."}]},"2":{"hr":[{"v":1,"t":"Saberite se, skupite, narode bestidni"},{"v":2,"t":"prije nego budete izgnani kao pljeva koja se u dan rasprši, prije nego stigne na vas plamen i gnjev Jahvin, prije nego stigne na vas dan gnjeva Jahvina."},{"v":3,"t":"Tražite Jahvu, svi skromni na zemlji, svi koji izvršavate odredbe njegove! Tražite pravdu, tražite poniznost: vi ćete možda biti zaštićeni u dan gnjeva Jahvina."},{"v":4,"t":"Da, Gaza će postati pustinja, Aškelon pustoš. Ašdod u puklo podne bit će izgnan, Ekron iz temelja iščupan."},{"v":5,"t":"Teško stanovnicima obale morske, narodu kretskome! Evo riječi Jahvine protivu vas: “Ja ću te poniziti, zemljo Filistejaca, uništit ću te, istrijebit ću sve tvoje stanovnike!"},{"v":6,"t":"I postat ćeš ispaša, pasište pastirsko i ograda za stado.”"},{"v":7,"t":"I taj kraj pripast će u dio Ostatku doma Judina; tu će oni izvoditi blago na pašu; uvečer se odmarati u kućama aškelonskim, jer će ih pohoditi Jahve, Bog njihov, i on će promijeniti sudbinu njihovu."},{"v":8,"t":"Čuo sam uvredu Moabovu i podrugivanja sinova Amonovih kad su vrijeđali moj narod i ponosili se zemljištem svojim."},{"v":9,"t":"“Zato, života mi moga!” - riječ je Jahve nad Vojskama, Boga Izraelova: “Moab će postati kao Sodoma i sinovi Amonovi kao Gomora: polje obraslo koprivom, hrpa soli pustoš dovijeka. Ostatak moga naroda oplijenit će ih, preostatak moga naroda zaposjest će ih.”"},{"v":10,"t":"To će biti cijena za njihovu oholost jer su se uznosili i rugali narodu Jahve nad Vojskama."},{"v":11,"t":"Za njih će Jahve biti strašan: kad uništi sve bogove zemaljske, pred njim će se pokloniti - svaki na svojoj zemlji - svi otoci naroda."},{"v":12,"t":"I vi, Etiopljani: “Vi ćete biti probijeni mojim mačem.”"},{"v":13,"t":"Zatim će svoju ruku dići protiv Sjevera i razrušit će zemlju asirsku, od Ninive će pustoš učiniti, suhu pustoš kao pustinja."},{"v":14,"t":"Usred nje će stado ležati, zvijeri svakojake; čaplje i pelikani počivat će noću na glavicama stupova, sova će hukati na prozoru, gavran graktati na pragu."},{"v":15,"t":"To li je veseli grad koji je stolovao u miru, koji je u svom srcu govorio: “Ja, i jedino ja!” Gledaj! Postade razvalina, brlog zvjerinji! Svi koji pokraj njega prolaze zvižde i mašu rukama."}]},"3":{"hr":[{"v":1,"t":"Teško nepokornom, okaljanom, nasilničkom gradu!"},{"v":2,"t":"On nikada nije čuo poziva, nikada nije prihvatio pouku; Jahvi on se nikada nije povjerio; svome Bogu nije se nikada približio."},{"v":3,"t":"Njegovi su knezovi usred njega - lavovi koji riču; njegovi su suci - vuci večernji koji do jutra nisu kosti glodali;"},{"v":4,"t":"proroci su njegovi - razmetljivci, puki lažljivci, svećenici njegovi skvrne Svetište, krše Zakon."},{"v":5,"t":"Usred njega, Jahve je pravedan - on ne čini nepravde; svako jutro iznosi svoju pravicu, u praskozorje ne izostaje; ali bezbožnik srama ne poznaje."},{"v":6,"t":"“Uništio sam narode, razorena su kruništa kula njihovih, poharao sam njihove ulice: nema više prolaznika! Razoreni su njihovi gradovi: nema ljudi, nema stanovnika!"},{"v":7,"t":"Govorio sam: 'Ti ćeš se mene ipak bojati, prigrlit ćeš pouku; u njihovim očima ne mogu nestati toliki moji pohodi.' Ali ne! - oni su žurno pokvarili sva djela svoja."},{"v":8,"t":"Zato mene čekajte - riječ je Jahvina - do dana kad ustanem kao tužilac; jer ja sam odredio da se sakupe narodi, da se saberu kraljevstva, da na vas gnjev svoj izlijem, svu gorčinu svoje srdžbe: u vatri moje ljubomore bit će sva zemlja sažgana."},{"v":9,"t":"Dat ću narodima čiste usne, da svi mogu zazivati ime Jahvino i služiti mu jednodušno."},{"v":10,"t":"S druge obale rijeka etiopskih prinosit će mi žrtvene darove moji štovaoci."},{"v":11,"t":"U onaj dan nećeš se sramiti svih svojih nedjela koja si protiv mene počinio, jer ću ukloniti iz tebe tvoje ohole hvalisavce; i nećeš se više šepiriti na Svetoj gori mojoj,"},{"v":12,"t":"jer ću pustiti da u tebi opstane samo skroman i čedan narod, i u imenu Jahvinu tražit će okrilje"},{"v":13,"t":"Ostatak Izraelov. Oni neće više činiti nepravdu, neće više govoriti laži; u njihovim ustima neće se više naći jezik prijevarni. Moći će pasti i odmarati se, i nitko im neće smetati.”"},{"v":14,"t":"Klikći od radosti, Kćeri sionska, viči od veselja, Izraele! Veseli se i raduj se iz sveg srca, Kćeri jeruzalemska!"},{"v":15,"t":"Jahve te riješio tvoje osude, neprijatelje tvoje uklonio! Jahve, kralj Izraelov, u sredini je tvojoj! Ne boj se više zla!"},{"v":16,"t":"U onaj dan reći će se Jeruzalemu: “Ne boj se, Sione! Neka ti ne klonu ruke!"},{"v":17,"t":"Jahve, Bog tvoj, u sredini je tvojoj, silni spasitelj! On će se radovati tebi pun veselja, obnovit će ti svoju ljubav, kliktat će nad tobom radosno"},{"v":18,"t":"kao u dan svečani. Odvratio sam od tebe nevolju da na sebi više ne nosiš sramotu."},{"v":19,"t":"Evo svladavam sve tvoje tlačitelje. U ono vrijeme izbavit ću sve hrome, sabrat ću prognane, pribavit im hvalu i diku po svoj zemlji gdje ih sramota bijaše dopala."},{"v":20,"t":"U ono vrijeme ja ću vas dovesti, u ono vrijeme ja ću vas sabrati! Tada ću vam dati hvalu i diku među narodima zemlje, kad okrenem vašu sudbinu pred vašim očima” - govori Jahve."}]}},"HAG":{"1":{"hr":[{"v":1,"t":"Druge godine kralja Darija, šestoga mjeseca, prvoga dana u mjesecu, dođe riječ Jahvina preko proroka Hagaja Zerubabelu, sinu Šealtielovu, namjesniku judejskom, i Jošui, sinu Josadakovu, velikom svećeniku:"},{"v":2,"t":"“Ovako govori Jahve nad Vojskama. Narod ovaj govori: 'Nije još došlo vrijeme da se opet sazda Dom Jahvin!'"},{"v":3,"t":"Zato je došla riječ Jahvina preko proroka Hagaja:"},{"v":4,"t":"A vama je vrijeme da stanujete u pokrivenim kućama, dok je ovaj Dom razvaljen."},{"v":5,"t":"I zato, ovako sada govori Jahve nad Vojskama: Razmotrite svoje putove!"},{"v":6,"t":"Sijete mnogo, malo dovozite; jedete, a niste siti; pijete, a napojit' se ne možete; odijevate se, a nije vam toplo. Poslenik zarađuje plaću, a stavlja je u prodrt tobolac!”"},{"v":7,"t":"Ovako govori Jahve nad Vojskama: “Razmotrite svoje putove!"},{"v":8,"t":"Idite na goru, dovezite drva i podignite opet Dom; bit će mi to milo i proslavit ću se” - govori Jahve."},{"v":9,"t":"“Nadaste se obilju, a gle, malo je; što dovezete kući, ja otpuhnem. A zašto?” - riječ je Jahve nad Vojskama. “Zato što je Dom moj razvaljen, dok se svaki od vas brine za dom svoj."},{"v":10,"t":"Stog' je nebo uskratilo rosu, a zemlja uskratila usjeve."},{"v":11,"t":"Ja dozvah sušu na zemlju i gore, na žito i vino, na ulje i na sve što zemlja rađa, na ljude i stoku i na svaki trudno stečen plod.”"},{"v":12,"t":"A Zerubabel, sin Šealtielov, i Jošua, sin Josadakov, veliki svećenik, i sav ostali narod poslušaše glas Jahve, Boga svojega, i riječi proroka Hagaja u onome radi čega ga Jahve njima posla: i narod se poboja Jahve."},{"v":13,"t":"Tada Hagaj, glasnik Jahvin, po Jahvinu nalogu ovako reče narodu: “Ja sam s vama” - riječ je Jahvina. -"},{"v":14,"t":"Jahve probudi duh Zerubabelu, sinu Šealtielovu, namjesniku judejskom, i duh Jošui, sinu Josadakovu, velikom svećeniku, i duh svemu ostalom narodu te oni dođoše i prionuše na posao u Domu Jahve nad Vojskama, Boga svojega."},{"v":15,"t":"Bijaše to dvadeset i četvrtoga dana šestog mjeseca."}]},"2":{"hr":[{"v":1,"t":"Druge godine kralja Darija, sedmoga mjeseca, dvadeset i prvoga dana u mjesecu, dođe riječ Jahvina preko proroka Hagaja:"},{"v":2,"t":"“Reci ovako Zerubabelu, sinu Šealtielovu, namjesniku judejskom, i Jošui, sinu Josadakovu, velikom svećeniku, i ostalom narodu:"},{"v":3,"t":"'Ima li još koga među vama koji vidje ovaj Dom u njegovoj staroj slavi? A kakva ga sada vi vidite? Prema onome, nije li to k'o ništa u vašim očima?"},{"v":4,"t":"Budi, dakle, junak, Zerubabele - riječ je Jahvina - budi junak, Jošua, sine Josadakov, veliki svećeniče! Budi junak, narode sve zemlje - riječ je Jahvina. Na posao! Jer, ja sam s vama! - riječ je Jahve nad Vojskama!"},{"v":5,"t":"Po obećanju što ga vama dadoh kad izađoste iz Egipta, duh moj posred vas ostaje. Ne bojte se!'"},{"v":6,"t":"Jer ovako govori Jahve nad Vojskama: 'Zamalo, i ja ću potresti nebesa i zemlju, i more i kopno."},{"v":7,"t":"Potrest ću sve narode da dođe blago svih naroda, i slavom ću napunit ovaj Dom' - kaže Jahve nad Vojskama."},{"v":8,"t":"'Moje je zlato, moje je srebro' - riječ je Jahve nad Vojskama."},{"v":9,"t":"'Slava ovoga drugog Doma bit će veća nego prvoga' - riječ je Jahve nad Vojskama. 'I na ovom ću mjestu dati mir' - riječ je Jahve nad Vojskama.”"},{"v":10,"t":"Dvadeset i četvrtoga dana devetoga mjeseca, druge godine kralja Darija, dođe riječ Jahvina preko proroka Hagaja:"},{"v":11,"t":"Ovako govori Jahve nad Vojskama. “Pitaj svećenike što kaže Zakon i reci:"},{"v":12,"t":"'Kad bi tko u skutu svoje haljine nosio posvećeno meso, ili bi se skutom dotakao kruha, jela, vina, ulja ili kakve god hrane, bi li to postalo sveto?'” Svećenici odgovoriše: “Ne!”"},{"v":13,"t":"Hagaj dalje upita: “Kad bi netko koji se onečistio dodirnuvši mrtvaca dotakao nešto od onoga, bi li to postalo nečisto?” Svećenici odgovoriše: “Bilo bi nečisto.”"},{"v":14,"t":"Onda Hagaj ovako reče: “Takav je i ovaj puk, takav je ovaj narod preda mnom - riječ je Jahvina - takvo je svako djelo ruku njihovih, i sve što ovdje prinose: sve je nečisto!”"},{"v":15,"t":"“A sada, promislite u srcu, od današnjega dana unapredak: Prije negoli se poče stavljati kamen na kamen u Jahvinu Svetištu,"},{"v":16,"t":"kakvi ono bijaste? Dolažaste hrpi od dvadeset mjerica, a bješe ih samo deset! Dolažaste kaci da zahvatite pedeset mjerica, a bješe ih samo dvadeset!"},{"v":17,"t":"Udarao sam snijeću, medljikom i grÓadom svako djelo vaših ruku, ali nikoga nema k meni” - riječ je Jahvina."},{"v":18,"t":"“Stoga dobro pripazite od današnjeg dana unapredak - od dvadeset i četvrtoga dana devetoga mjeseca, kad se stao graditi Hram Jahvin, pripazite dobro"},{"v":19,"t":"ima li još žita u žitnici? Ni vinova loza ni smokva, ni mogranj ni maslina nisu rađali! Al' od ovog dana ja ću blagosloviti.”"},{"v":20,"t":"Dvadeset i četvrtoga dana istoga mjeseca dođe riječ Jahvina Hagaju drugi put:"},{"v":21,"t":"“Reci ovako Zerubabelu, namjesniku judejskom: 'Ja ću potresti nebesa i zemlju!"},{"v":22,"t":"Oborit ću prijestolja kraljevstvima i uništit ću moć kraljevima naroda. Prevrnut ću bojna kola i one na njima, konji i konjanici njihovi bit će oboreni, past će od mača brata svojega.'”"},{"v":23,"t":"“Toga dana” - riječ je Jahve nad Vojskama - “uzet ću te, Zerubabele, sine Šealtielov, slugo moja” - riječ je Jahvina - “i stavit ću te kao pečatnjak, jer tebe izabrah” - riječ je Jahve nad Vojskama."}]}},"ZEC":{"1":{"hr":[{"v":1,"t":"Osmoga mjeseca druge godine Darijeve dođe riječ Jahvina proroku Zahariji, sinu Berekjinu, sinu Idonovu."},{"v":2,"t":"“Jahve se teško razgnjevio na oce vaše!"},{"v":3,"t":"Zatim im reci: 'Ovako govori Jahve nad Vojskama: Vratite se meni, i ja ću se vratiti vama' - riječ je Jahve nad Vojskama."},{"v":4,"t":"'Ne budite poput svojih otaca koje su pozivali negdašnji proroci.' Ovako govori Jahve nad Vojskama: 'Vratite se sa zlih putova svojih i od zlih djela. Ali oni nisu slušali ni pazili na mene' - govori Jahve."},{"v":5,"t":"Gdje su sad oci vaši? Zar će dovijeka živjeti proroci?"},{"v":6,"t":"Ali moje riječi i odredbe, koje sam naložio slugama svojim prorocima, nisu li stigle vaše oce? Oni se obratiše i priznaše: 'Jahve nad Vojskama učinio je s nama kako bijaše namislio učiniti prema našim putovima i našim djelima.'”"},{"v":7,"t":"Dvadeset i četvrtog dana, jedanaestoga mjeseca, a to je mjesec Šebat, druge godine Darijeve, dođe riječ Jahvina proroku Zahariji, sinu Berekjinu, sinu Idonovu."},{"v":8,"t":"Imao sam noću viđenje. Gle, na riđanu čovjek jaše među mirtama koje imaju duboko korijenje, a iza njega konji riđi, smeđi i bijeli."},{"v":9,"t":"Upitah: “Koji su ovi, gospodaru?” Anđeo koji je sa mnom govorio reče mi: “Ja ću ti pokazati koji su.”"},{"v":10,"t":"Čovjek koji stajaše među mirtama odgovori: “Ovo su oni koje je poslao Jahve da obilaze zemlju.”"},{"v":11,"t":"Oni se obratiše anđelu Jahvinu, koji stajaše među mirtama, i kazaše: “Obišli smo zemlju, i gle: sva zemlja počiva i miruje.”"},{"v":12,"t":"Tada progovori anđeo Jahvin i reče: “Jahve nad Vojskama, kada ćeš se već jednom smilovati Jeruzalemu i gradovima judejskim na koje se već sedamdeset godina ljuto srdiš?”"},{"v":13,"t":"A Jahve anđelu koji je govorio sa mnom odgovori utješnim riječima."},{"v":14,"t":"I anđeo koji je govorio sa mnom reče mi: “Objavi ovo: 'Ovako govori Jahve nad Vojskama: Ljubavlju ljubomornom gorim za Jeruzalem i za Sion,"},{"v":15,"t":"a velikim gnjevom plamtim na ohole narode, jer kad se ono malo rasrdih, oni prijeđoše mjeru.'"},{"v":16,"t":"Zato ovako govori Jahve: 'Vraćam se Jeruzalemu s milosrđem; opet će u njemu sagraditi Dom moj' - riječ je Jahve nad Vojskama - 'i opet će se u Jeruzalemu protezati uže mjeračko.'"},{"v":17,"t":"I ovo poruči: 'Ovako govori Jahve nad Vojskama: Moji će se gradovi opet prelijevati obiljem, i Jahve će utješiti Sion, izabrati Jeruzalem.'”"}]},"2":{"hr":[{"v":1,"t":"Podigoh oči i vidjeh. I gle: četiri roga."},{"v":2,"t":"Upitah anđela koji je govorio sa mnom: “Što je ovo?” On mi odgovori: “To su rogovi koji su raznijeli Judu, Izraela i Jeruzalem.”"},{"v":3,"t":"Onda mi Jahve pokaza četiri kovača."},{"v":4,"t":"A ja upitah: “Što su došli ovi raditi?” On mi odgovori: “Ono su rogovi koji su raznijeli Judu te se nitko više ne usuđuje dići glavu; a ovi su došli da ih zastraše i da slome rogove narodima koji podizahu rog na zemlju Judinu kako bi je raznijeli.”"},{"v":5,"t":"Podigoh oči i vidjeh. I gle: čovjek, a u ruci mu mjeračko uže."},{"v":6,"t":"Upitah ga: “Kamo ideš?” Odgovori mi: “Da izmjerim Jeruzalem i da vidim koliko je širok a koliko dug.”"},{"v":7,"t":"I gle, anđeo koji je govorio sa mnom stajaše nepomično, a drugi mu iziđe u susret"},{"v":8,"t":"i reče mu: “Trči, reci onome mladiću ovako: Jeruzalem će biti kao otvoren grad radi mnoštva ljudi i stoke koji će biti u njemu."},{"v":9,"t":"A ja ću mu - riječ je Jahvina - biti ognjen zid unaokolo i Slava njegova sred njega.”"},{"v":10,"t":"“Hej! Hej! Bježite iz zemlje sjeverne” - riječ je Jahvina - “jer u sva četiri vjetra nebeska razasuo sam vas” - riječ je Jahvina!"},{"v":11,"t":"“Hej, Sione, koji živiš kod kćeri babilonske, spasi se!”"},{"v":12,"t":"Ovako govori Jahve nad Vojskama, čija me Slava izaslala k narodima koji su vas opljačkali: “Tko vas dira, dira mi zjenicu oka."},{"v":13,"t":"Gle, ruku dižem na njih da plijenom budu svojim robovima.” Znat ćete tako da me posla Jahve nad Vojskama!"},{"v":14,"t":"“Kliči i raduj se, kćeri sionska, jer evo, dolazim usred tebe prebivat' - riječ je Jahvina."},{"v":15,"t":"U onaj dan mnogi će narodi uz Jahvu prionuti i bit će narod moj, a ja ću prebivati usred tebe.” Znat ćeš tako da me tebi posla Jahve nad Vojskama."},{"v":16,"t":"I Judeja će biti baština Jahvina, njegov dio u Svetoj zemlji, i on će opet izabrati Jeruzalem."},{"v":17,"t":"Tiho, ljudi svi, pred Jahvom, jer, evo, on ustaje iz svetoga Prebivališta svojega!"}]},"3":{"hr":[{"v":1,"t":"Potom mi pokaza Jošuu, velikog svećenika, koji stajaše pred anđelom Jahvinim, i Satana, koji mu stajaše zdesna da ga tuži."},{"v":2,"t":"Anđeo Jahvin reče Satanu: “Suzbio te Jahve, Satane! Suzbio te Jahve koji izabra Jeruzalem! Nije li on glavnja iz ognja izvučena?”"},{"v":3,"t":"A Jošua bijaše obučen u prljave haljine dok stajaše pred anđelom Jahvinim."},{"v":4,"t":"Anđeo se obrati onima koji pred njim stajahu i reče im: “Skinite s njega te prljave haljine!” I reče mu: “Evo, skidam s tebe tvoju krivicu i odijevam te u dragocjenu haljinu!”"},{"v":5,"t":"I nastavi: “Stavite mu čist povez oko glave!” Oni mu staviše čist povez oko glave i odjenuše ga u dragocjene haljine u nazočnosti anđelovoj."},{"v":6,"t":"I anđeo Jahvin upozori Jošuu:"},{"v":7,"t":"“Ovako govori Jahve nad Vojskama: 'Ako budeš mojim putovima hodio i mojih se pridržavao naredaba, ti ćeš biti upravitelj u Domu mojemu, čuvat ćeš moja predvorja i dat ću ti pristup među one koji ondje stoje."},{"v":8,"t":"Poslušaj, dakle, Jošua, veliki svećeniče, ti i drugovi tvoji koji su oko tebe, jer vi ste ljudi znamenja! Evo, ja ću dovesti Izdanak, Slugu svojega, i uklonit ću opačinu ove zemlje u jedan dan."},{"v":9,"t":"Jer evo kamena koji stavljam pred Jošuu: na tom je kamenu sedam očiju i u nj ću urezati natpis' - riječ je Jahve nad Vojskama."},{"v":10,"t":"'U dan onaj' - riječ je Jahve nad Vojskama - 'pozivat ćete jedan drugoga pod lozu i pod smokvu.'”"}]},"4":{"hr":[{"v":1,"t":"Anđeo koji je govorio sa mnom vrati se tad i probudi me kao čovjeka koji se oda sna budi."},{"v":2,"t":"“Što vidiš?” - upita. Ja odgovorih: “Vidim, evo, svijećnjak, sav od zlata, s posudom za ulje vrh njega; i sedam je žižaka na svijećnjaku, sa sedam lijevaka za sedam žižaka što su na njemu."},{"v":3,"t":"Dvije su masline kraj njega, jedna njemu zdesna, druga slijeva.”"},{"v":4,"t":"Obratih se anđelu koji je govorio sa mnom i upitah ga: “Što je to, gospodaru?”"},{"v":5,"t":"Anđeo koji je govorio sa mnom odgovori mi: “Zar ne znaš što je to?” Ja rekoh: “Ne, gospodaru.”"},{"v":6,"t":"[6a] On mi tad odgovori ovako: [6b]Evo riječi Jahvine Zerubabelu: “Ne silom niti snagom, već duhom mojim!” - riječ je Jahve nad Vojskama."},{"v":7,"t":"Što si ti, goro velika? Pred Zreubabelom postaješ ravnica! On će izvući krunišni kamen uz poklike: “Hvala! Hvala za njega!”"},{"v":8,"t":"Dođe mi potom riječ Jahvina:"},{"v":9,"t":"Zerubabelove su ruke ovaj Dom utemeljile, njegove će ga ruke završiti. I vi ćete znati da me k vama poslao Jahve nad Vojskama."},{"v":10,"t":"[10a] Jer, tko je prezreo dan skromnih početaka? Radovat će se kad vide olovni visak u ruci Zerubabelovoj. [10b] “Ovih sedam oči su Jahvine što strijeljaju po svoj zemlji.”"},{"v":11,"t":"Tad progovorih i zapitah ga: “Što su one dvije masline desno i lijevo od svijećnjaka?”"},{"v":12,"t":"Progovorih opet i upitah ga: “Što su one dvije maslinove grančice koje kroz dvije zlatne cijevi dolijevaju ulje?”"},{"v":13,"t":"On mi odgovori: “Zar ne znaš što je to?” Odvratih: “Ne, gospodaru!”"},{"v":14,"t":"On reče: “To su dva Pomazanika koji stoje pred Gospodarem sve zemlje.”"}]},"5":{"hr":[{"v":1,"t":"Podigoh opet oči i vidjeh: leti svitak knjige."},{"v":2,"t":"Anđeo me upita: “Što vidiš?” Odgovorih: “Vidim svitak knjige gdje leti: dužina joj je dvadeset lakata, a širina deset.”"},{"v":3,"t":"On mi tad reče: “To je prokletstvo koje će zahvatiti svu zemlju; odsad, svaki koji krade bit će po njem izgnan odavde i svaki koji krivo priseže bit će po njem odavde protjeran."},{"v":4,"t":"Ja ću ga izvesti - riječ je Jahve nad Vojskama - da uđe u kuću lupežu i u kuću onome koji se krivo kune mojim imenom te da boravi usred njegove kuće i uništi je skupa s njenim drvljem i kamenjem.”"},{"v":5,"t":"Anđeo koji je govorio sa mnom iziđe i reče mi: “Podigni oči i pogledaj što se to pojavljuje.”"},{"v":6,"t":"Ja ga upitah: “Što je to?” On reče: “To se pojavljuje efa.” I nastavi: “To je opća pokvarenost na zemlji.”"},{"v":7,"t":"I gle, podiže se olovan poklopac i jedna žena sjedi usred efe."},{"v":8,"t":"On reče: “To je zloća.” I gurnu je u efu i baci joj na otvor olovni poklopac."},{"v":9,"t":"Podigavši oči, vidjeh: dvije žene izlaze s vjetrom u krilima, a krila im bijahu kao krila rode; one podigoše efu između zemlje i neba."},{"v":10,"t":"Upitah tad anđela koji je govorio sa mnom: “Kamo odnose efu?”"},{"v":11,"t":"On mi odgovori: “Da joj sagrade hram u zemlji šinearskoj i da joj pripreme postolje na koje će je postaviti.”"}]},"6":{"hr":[{"v":1,"t":"I podigoh oči i vidjeh: gle, četvera bojna kola izlaze između dviju gora; a gore bijahu od mjedi."},{"v":2,"t":"U prvim kolima bijahu riđi konji; u drugim kolima crni konji;"},{"v":3,"t":"u trećim kolima bijeli konji, a u četvrtim kolima konji šareni."},{"v":4,"t":"Obratih se anđelu koji je govorio sa mnom i upitah ga: “Što je to, gospodaru?”"},{"v":5,"t":"Anđeo mi odgovori ovako: “Ti kreću u četiri vjetra nebeska pošto su stajali pred Gospodarem sve zemlje."},{"v":6,"t":"Riđani kreću u zemlju istočnu; vranci u zemlju sjevernu; bijelci kreću u zemlju zapadnu, a šarci kreću u zemlju južnu.”"},{"v":7,"t":"Krepko oni stupaju, nestrpljivi da obiđu zemlju. On im reče: “Idite, obiđite zemlju!” I oni krenuše obilaziti zemljom."},{"v":8,"t":"On me zovnu i reče mi: “Vidi, oni koji su krenuli u sjevernu zemlju umirit će gnjev moj u zemlji sjevernoj.”"},{"v":9,"t":"I dođe mi riječ Jahvina:"},{"v":10,"t":"“Uzmi prinose od izgnanika - od Heldaja, Tobije i Jedaje - i pođi danas i uđi u dom Jošije, sina Sefanijina, koji je došao iz Babilona."},{"v":11,"t":"Uzmi srebra i zlata, načini krunu i stavi na glavu Jošui, sinu Josadakovu, velikom svećeniku."},{"v":12,"t":"I reci mu: 'Ovako govori Jahve nad Vojskama: Evo čovjeka komu je ime Izdanak; ispod njega će proklijati i on će sazdati Svetište Jahvino."},{"v":13,"t":"On će sazdati Svetište Jahvino i proslaviti se. On će sjediti i vladati na prijestolju. A do njega će na prijestolju biti svećenik. Sklad savršen bit će među njima."},{"v":14,"t":"A kruna neka ostane u Jahvinu Svetištu za spomen Heldaju, Tobiji, Jedaji i Jošiji, sinu Sefanijinu."},{"v":15,"t":"I oni koji su daleko doći će i sazdat će Svetište Jahvino. Znat ćete tako da me Jahve nad Vojskama k vama poslao.' To će se zbiti ako zaista poslušate glas Jahve, Boga svojega.”"}]},"7":{"hr":[{"v":1,"t":"Četvrte godine kralja Darija, četvrtoga dana devetoga mjeseca, Kisleva, dođe riječ Jahvina Zahariji."},{"v":2,"t":"Betel je naime poslao Sar-Esera i Regem-Meleka s njihovim ljudima da mole lice Jahvino"},{"v":3,"t":"i da pitaju svećenike u Domu Jahve nad Vojskama i proroke: “Hoćemo li plakati petoga mjeseca i postiti, kao što činimo već tolike godine?”"},{"v":4,"t":"Tada mi dođe riječ Jahve nad Vojskama: “Reci svemu puku zemlje i svećenicima:"},{"v":5,"t":"'Kad postite i naričete petoga i sedmoga mjeseca već sedamdeset godina, zar meni postite?"},{"v":6,"t":"A kad jedete i pijete, zar sebi ne jedete i pijete?"},{"v":7,"t":"Nisu li to propisi koje je Jahve objavio preko negdašnjih proroka kada Jeruzalem bijaše naseljen i miran kao i gradovi oko njega i kada bijaše napučen Negeb i Šefela?'”"},{"v":8,"t":"Riječ Jahvina dođe Zahariji:"},{"v":9,"t":"“Ovako govori Jahve nad Vojskama: 'Sudite istinito i budite dobrostivi i milosrdni jedni drugima."},{"v":10,"t":"Ne tlačite udovu ni sirotu, ni došljaka ni uboga, i ne snujte u srcu pakosti jedan prema drugom.'"},{"v":11,"t":"Ali oni ne htjedoše poslušati, već prkosno okrenuše leđa; zatisnuše uši da ne bi čuli;"},{"v":12,"t":"otvrdnuše srcem kao kremen, da ne bi čuli Zakon i riječi koje im je slao Jahve nad Vojskama, svojim duhom, preko drevnih proroka. I Jahve nad Vojskama silno se tad razgnjevi."},{"v":13,"t":"I zato, kao što je on zvao a oni ga ne slušaše, tako su sad oni zvali a ja ih nisam slušao - riječ je Jahve nad Vojskama."},{"v":14,"t":"I razmeo sam ih među sve narode kojih ne poznavahu, a zemlja iza njih bi opustošena, te nitko nije njome prolazio niti se vraćao. Tako su zemlju blagostanja obratili u pustoš!”"}]},"8":{"hr":[{"v":1,"t":"I dođe mi riječ Jahvina:"},{"v":2,"t":"“Ovako govori Jahve nad Vojskama: 'Ljubavlju ljubomornom za Sion izgaram i gnjevom velikim plamtim za nj! Vraćam se u Sion, prebivati hoću sred Jeruzalema.'"},{"v":3,"t":"Ovako govori Jahve nad Vojskama: 'Jeruzalem će se zvati Gradom vjernosti i Gorom Jahve nad Vojskama, Gorom svetosti.'"},{"v":4,"t":"Ovako govori Jahve nad Vojskama: 'Starci i starice opet će posjedati po trgovima jeruzalemskim, svatko sa štapom u ruci zbog starosti prevelike."},{"v":5,"t":"A gradski će se trgovi ispuniti dječacima i djevojčicama koji će se igrati na njegovim trgovima.'"},{"v":6,"t":"Ovako govori Jahve nad Vojskama: 'Ako to bude čudo u očima Ostatka u dane one, zar će to biti čudo i u mojim očima' - riječ je Jahve nad Vojskama."},{"v":7,"t":"Ovako govori Jahve nad Vojskama: 'Evo spasit ću svoj narod iz zemlje istočne i iz zemlje sunčanog zapada."},{"v":8,"t":"Ja ću ih dovesti da se nastane usred Jeruzalema. I bit će mi narod a ja ću im biti Bog u vjernosti i pravdi.'"},{"v":9,"t":"Ovako Govori Jahve nad Vojskama: 'Neka ojačaju ruke vama koji ovih dana slušate riječi ove iz usta proroka koji prorokuje od dana kada bjehu položeni temelji Domu Jahve nad Vojskama da bi se opet sagradilo Svetište."},{"v":10,"t":"Jer, prije ovih dana ne bijaše nadnice za čovjeka niti nadnice za živinče; niti bijaše mira od neprijatelja onome koji je izlazio ni onome koji je dolazio; puštao sam ljude jedne protiv drugih."},{"v":11,"t":"Ali sada, neću biti prema Ostatku ovog naroda kao minulih dana - riječ je Jahve nad Vojskama -"},{"v":12,"t":"nego ću posijati mir: loza će roditi grožđem, zemlja će davati usjeve, a nebo će davati rosu svoju. Sve ću to dati Ostatku ovoga naroda."},{"v":13,"t":"I kao što bijaste prokletstvo među narodima, dome Judin i dome Izraelov, tako ću vas spasiti da budete blagoslovom! Ne bojte se, nek' vam jake budu ruke!'"},{"v":14,"t":"Jer ovako govori Jahve nad Vojskama: 'Kao što bijah namislio unesrećiti vas kada su me razgnjevili oci vaši - govori Jahve nad Vojskama - i nisam se pokajao,"},{"v":15,"t":"tako, promijenivši naum, u ove dane mislim usrećiti Jeruzalem i dom Judin. Ne bojte se!"},{"v":16,"t":"A ovo vam je činiti: Govorite istinu jedan drugom; sudite istinito i miroljubivo na vratima gradskim!"},{"v":17,"t":"Ne snujte jedan drugome zlo u srcu; ne ljubite lažnu kletvu. Jer sve to ja mrzim' - riječ je Jahvina!”"},{"v":18,"t":"Dođe mi riječ Jahve nad Vojskama:"},{"v":19,"t":"“Ovako govori Jahve nad Vojskama: Post četvrtoga, post petoga, post sedmoga i post desetoga mjeseca postat će za Dom Jahvin radost, veselje i veseli blagdani. Ali ljubite istinu i mir!”"},{"v":20,"t":"“Ovako govori Jahve nad Vojskama: Još će dolaziti narodi i stanovnici mnogih gradova."},{"v":21,"t":"Stanovnici jednoga grada ići će u drugi govoreći: 'Hajde da idemo moliti lice Jahvino i tražiti Jahvu nad Vojskama!' Ići ću i ja!"},{"v":22,"t":"I doći će mnogi puk i moćni će narodi tražiti Jahvu nad Vojskama u Jeruzalemu i moliti lice Jahvino."},{"v":23,"t":"Ovako govori Jahve nad Vojskama! U one će dane deset ljudi od naroda svih jezika hvatati jednog Židova za skut govoreći: 'Idemo s vama, jer čusmo da je s vama Bog.'”"}]},"9":{"hr":[{"v":1,"t":"Proroštvo. Riječ Jahvina. Jahve prolazi zemljom Hadraka, Damask mu je počivalište; jer Jahvini su gradovi Arama i sva plemena Izraela."},{"v":2,"t":"Hamat također, koji s njim graniči,"},{"v":3,"t":"i Tir i Sidon, tako mudar. Tir podiže tvrde bedeme, zgrnu srebra kao prašine i zlata kao blata s ulica."},{"v":4,"t":"Al' evo, Gospod će ga osvojiti, survati u more moć njegovu, a njega će progutati oganj."},{"v":5,"t":"Vidjet će to Aškelon i prestrašiti se, a Gaza sva će uzdrhtati, i Ekron, jer ga nada prevari: nestat će kralja iz Gaze, Aškelon će pust ostati,"},{"v":6,"t":"u Ašdodu stanovat će kopilad! Zatrt ću ponos Filistejaca,"},{"v":7,"t":"uklonit ću im krv iz usta i gnusobu iz zuba. I oni će pripasti Bogu našem i bit će kao jedna obitelj u Judeji, a Ekron će biti kao Jebusejac."},{"v":8,"t":"Uz Dom svoj utaborit ću se kao straža, protiv onih koji odlaze i dolaze; tlačitelj neće više ovud prolaziti, jer njegovu sam uvidio bijedu."},{"v":9,"t":"Klikni iz sveg grla, Kćeri sionska! Viči od radosti, Kćeri jeruzalemska! Tvoj kralj se evo tebi vraća: pravičan je i pobjedonosan, ponizan jaše na magarcu, na magaretu, mladetu magaričinu."},{"v":10,"t":"On će istrijebit' kola iz Efrajima i konje iz Jeruzalema; on će istrijebit' luk ubojni. On će navijestit' mir narodima; vlast će mu se proširit' od mora do mora i od Rijeke do rubova zemlje."},{"v":11,"t":"A i tebi, zbog krvi tvoga Saveza, vratit ću sužnje tvoje iz jama bezvodnih."},{"v":12,"t":"Vratite se u Tvrđavu, izgnanici puni nade, još danas - ja navješćujem - dvostruko ću ti uzvratiti."},{"v":13,"t":"Jer, Judu sam kao luk napeo, a Efrajimom luk naoružao: tvoje ću, o Sione, zavitlat' sinove - protiv sinova tvojih, o Javane - i učinit ću te kao mač junaka."},{"v":14,"t":"Nad njima tad će se pojaviti Jahve i kao munja letjet će mu strijela. Jahve Gospod u rog će zatrubit', hodit će na južnim vihorima."},{"v":15,"t":"Jahve nad Vojskama zakrilit će ih i oni će gaziti nogama kamenje praćaka, pit će krv kao da je vino, napojit' se kao škropilo, kao uglovi na žrtveniku."},{"v":16,"t":"Jahve Bog njihov spasit će ih u dan onaj; kao stado on će pasti narod svoj; kao drago kamenje krune oni će blistat' u zemlji njegovoj."},{"v":17,"t":"Ah, kako li će sretan, kako lijep biti! Od žita će rasti mladići, a od slatkog vina djevice."}]},"10":{"hr":[{"v":1,"t":"Tražite od Jahve dažda u vrijeme proljetno! Jahve stvara munje i daje kišu; čovjeku kruh daje, a stoci travu."},{"v":2,"t":"Lažno bajaju kumiri, prijevaru vide gatari, obmanu govore snovi, varljivu utjehu daju, zato kao stado blude ljudi, lutaju jer nemaju pastira."},{"v":3,"t":"Moj je gnjev planuo na pastire, i ja ću kaznom pohodit jarce. Da, Jahve nad Vojskama pohodit će stado svoje, dom Judin. I učinit će da budu k'o gizdav konj u boju:"},{"v":4,"t":"od njega će poteći kamen zaglavni, klin šatorski, od njega ubojit luk, od njega sve vođe."},{"v":5,"t":"Bit će zajedno kao junaci što u boju gaze kao po blatu uličnom; vojevat će, jer Jahve je s njima, i osramotit će one koji konje jašu."},{"v":6,"t":"“Ojačat ću dom Judin, spasiti dom Josipov. Opet ću ih naseliti, žao mi ih, i bit će kao da ih nisam odbacio, jer ja sam Jahve, Bog njihov - uslišat ću ih.”"},{"v":7,"t":"Efrajimci bit će kao junaci i radostit će im se srce kao od vina: vidjet će sinove svoje i veseliti se, u Jahvi će klicati srce njihovo."},{"v":8,"t":"“Zazviždat ću im i sabrati ih, jer ja sam ih izbavio, bit će opet brojni kao što bjehu."},{"v":9,"t":"Rasijao sam ih među narode, ali će se oni u zemljama dalekim spomenuti mene, poučit će svoje sinove, i oni će se vratiti."},{"v":10,"t":"Vratit ću ih iz zemlje egipatske, sabrat ću ih iz Asirije i dovest ih u zemlju gileadsku i na Libanon, i neće biti dosta mjesta za njih.”"},{"v":11,"t":"Prijeći će more egipatsko, jer on će udariti valove morske, sve dubine Nila presahnut će. Bit će oboren ponos Asirije, oduzeto žezlo Egiptu."},{"v":12,"t":"U Jahvi će biti snaga njihova, njegovim će se oni proslavit imenom - riječ je Jahvina."}]},"11":{"hr":[{"v":1,"t":"Otvori vrata, Libanone, nek' ti oganj sažeže cedrove!"},{"v":2,"t":"Kukaj, čempresu, jer pade cedar, jer su mogućnici upropašteni! Kukajte, hrastovi bašanski, jer posječena je šuma najgušća."},{"v":3,"t":"Čuj jauk pastira, opustošen je sjaj njihov! Čuj riku lavića, opustošen je ponos jordanski!"},{"v":4,"t":"Ovako mi reče Jahve:"},{"v":5,"t":"“Pasi ovce klanice! Kupci ih njihovi kolju nekažnjeno, a koji ih prodaju, govore: 'Blagoslovljen bio Jahve, obogatio sam se!' i pastiri ih njihovi ne štede."},{"v":6,"t":"Ni ja više neću štedjeti žitelja zemlje - riječ je Jahve nad Vojskama - nego: predajem, evo, svakoga u ruke njegova bližnjega i u ruke kralja njegova; i oni će pustošiti zemlju, a ja neću izbavljati iz ruku njihovih.”"},{"v":7,"t":"Stadoh pasti ovce klanice za trgovce ovcama te uzeh dva štapa: jedan nazvah Naklonost, drugi Sveza. Tako sam pasao stado."},{"v":8,"t":"I u jednom mjesecu odbacih tri pastira. Ali mi i ovce dojadiše, omrznuh im."},{"v":9,"t":"Tad rekoh: “Neću vas više pasti! Koja mora uginuti, nek' ugine! Koja mora nestati, nek' nestane! A koje ostanu, neka jedna drugoj meso prožderu!”"},{"v":10,"t":"Tad uzeh svoj štap Naklonost i slomih ga da raskinem Savez svoj što ga bijah sklopio sa svim narodima."},{"v":11,"t":"I on se raskinu onog dana, i trgovci ovcama koji su to gledali doznaše da je to bila riječ Jahvina."},{"v":12,"t":"Rekoh im tad: “Ako vam je to dobro, dajte mi plaću; ako nije, nemojte.” Oni mi odmjeriše plaću: trideset srebrnika."},{"v":13,"t":"A Jahve mi reče: “Baci u riznicu tu lijepu cijenu kojom su me procijenili!” Ja uzeh trideset srebrnika i bacih u riznicu u Domu Jahvinu."},{"v":14,"t":"Onda slomih i svoj drugi štap, Svezu - da raskinem bratstvo između Jude i Izraela."},{"v":15,"t":"I reče mi Jahve: “Uzmi još opremu bezumna pastira,"},{"v":16,"t":"jer, evo, podići ću jednoga bezumnog pastira u ovoj zemlji: za izgubljene on se neće brinuti, zalutale neće tražiti, ranjene neće vidati, iscrpljene neće nositi, nego će jesti meso od pretilih i papke im otkidati."},{"v":17,"t":"Teško pastiru opakom koji stado ostavlja! Neka mu mač stigne ruku i desno oko! Nek' mu desnica sasvim usahne, oko desno sasvim potamni!”"}]},"12":{"hr":[{"v":1,"t":"Proroštvo. Besjeda Jahvina o Izraelu. Govori Jahve koji razape nebesa, utemelji zemlju i stvori dah čovjeku u grudima:"},{"v":2,"t":"“Evo, učinit ću Jeruzalem čašom opojnom svim narodima uokolo - za opsade Jeruzalema."},{"v":3,"t":"U onaj dan učinit ću Jeruzalem teškim kamenom svim narodima: svi koji ga budu dizali teško će se izraniti, a skupit će se na nj svi narodi zemlje."},{"v":4,"t":"U onaj dan - riječ je Jahvina - udarit ću sve konje strahom, a njine jahače mahnitošću. Ali nad domom Judinim otvorit ću oči, a sljepilom ću udariti sve konje narodÄa."},{"v":5,"t":"Tada će u srcu reći plemena Judina: 'Snaga je Jeruzalemaca u Jahvi nad Vojskama, Bogu njihovu!'"},{"v":6,"t":"U onaj dan učinit ću da plemena Judina budu kao žeravnica užarena na drvlju, kao baklja upaljena na snoplju: i proždirat će zdesna i slijeva sve narode uokolo. A Jeruzalem će i dalje stajati na svome mjestu.”"},{"v":7,"t":"Jahve će najprije spasiti Judine šatore da se ponos doma Davidova i ponos Jeruzalemaca ne izdigne iznad Jude."},{"v":8,"t":"U onaj dan Jahve će zakriliti Jeruzalemce: najsustaliji među njima bit će u onaj dan kao David, a dom Davidov bit će kao božanstvo, kao Anđeo Jahvin pred njima."},{"v":9,"t":"“U onaj dan pregnut ću da uništim sve narode koji dođu na Jeruzalem."},{"v":10,"t":"A na dom Davidov i na Jeruzalemce izlit ću duh milosni i molitveni. I gledat će na onoga koga su proboli; naricat će nad njim kao nad jedincem, gorko ga oplakivati kao prvenca."},{"v":11,"t":"U onaj dan plač velik će nastati u Jeruzalemu, poput plača hadad-rimonskog u ravnici megidonskoj."},{"v":12,"t":"I plakat će zemlja, svaka porodica napose, i žene njihove napose; porodica doma Davidova napose, i žene njihove napose; porodica doma Natanova napose, i žene njihove napose;"},{"v":13,"t":"porodica doma Levijeva napose, i žene njihove napose; porodica Šimejeva napose, i žene njihove napose;"},{"v":14,"t":"i sve ostale porodice, svaka porodica za sebe, i žene njihove napose."}]},"13":{"hr":[{"v":1,"t":"U onaj dan otvorit će se izvor domu Davidovu i Jeruzalemcima da se operu od grijeha i nečistoće."},{"v":2,"t":"U onaj dan - riječ je Jahve nad Vojskama - iskorijenit ću iz zemlje imena kumirÄa da se više ne spominju; uklonit ću iz zemlje i proroke i duh nečistoće."},{"v":3,"t":"Ako netko još bude prorokovao, otac i mati koji su ga rodili reći će mu: 'Nećeš više živjeti, jer laž govoriš u ime Jahvino!' Otac i mati koji su ga rodili probost će ga kada bude prorokovao."},{"v":4,"t":"U onaj dan svaki će se prorok stidjeti svoga viđenja; neće se više ogrtati plaštem od kostrijeti da bi lagali,"},{"v":5,"t":"nego će govoriti: 'Nisam ja prorok; ja sam ratar, zemlja je moje dobro od mladosti!'"},{"v":6,"t":"Ako li ga tko upita: 'Kakve su ti to rane po tijelu?' on će odgovoriti: 'Izranjen sam kod prijateljÄa.'"},{"v":7,"t":"Probudi se, maču, protiv mog pastira, protiv čovjeka, moga srodnika - riječ je Jahve nad Vojskama. Udari pastira, i ovce će se razbjeći! Okrenut ću ruku protiv slabića,"},{"v":8,"t":"i u svoj će zemlji - riječ je Jahvina - dvije trećine biti istrijebljene, a trećina ostavljena."},{"v":9,"t":"Tu ću trećinu kroz oganj provesti, pročistit ću ih kao što se pročišćuje srebro, iskušat' ih kao što se srebro iskušava. I on će zazivati ime moje, a ja ću mu se odazvati; i reći ću: 'Moj je to narod!' a on će reći: 'Jahve je Bog moj!'”"}]},"14":{"hr":[{"v":1,"t":"Gle, dolazi dan Jahvin kada će se podijeliti plijen usred tebe."},{"v":2,"t":"I sabrat ću sve narode u Jeruzalem u borbu. I zaposjest će grad, opljačkati kuće i silovati žene. Polovina će grada otići u izgnanstvo, ali Ostatak neće biti istrijebljen iz grada."},{"v":3,"t":"Tada će Jahve izaći i boriti se protiv tih naroda kako on zna ratovati u dan ratni."},{"v":4,"t":"Noge će mu, u dan onaj, stajati na Gori maslinskoj koja je nasuprot Jeruzalemu na istoku. I raskolit će se Gora maslinska po srijedi, između istoka i zapada, u golemu dolinu: jedna će se polovina pomaknuti na sjever, druga na jug."},{"v":5,"t":"Dolina Gore moje bit će ispunjena od Goe pa do Jasola i bit će zakrčena kao što je bila zakrčena poslije potresa u dane Uzije, kralja judejskog. Tada će doći Jahve, Bog tvoj, i svi sveci s njim."},{"v":6,"t":"U dan onaj neće više biti ni studeni ni leda."},{"v":7,"t":"Bit će to dan čudesan - znade ga Jahve - ni dan ni noć; i u vrijeme večeribit će svjetlo."},{"v":8,"t":"U onaj dan žive će vode poteći iz Jeruzalema, pola k moru istočnom, pola kmoru zapadnom. Bit će tako ljeti i zimi."},{"v":9,"t":"I Jahve će biti kralj nad svom zemljom."},{"v":10,"t":"Sva će se zemlja pretvoriti u ravnicu, od Gebe do Rimona negepskog. A Jeruzalem će se uzvisiti na svom mjestu; i bit će nastanjen - od Vrata Benjaminovih do Prvih vrata, to jest do Vrata ugaonih, i od Kule Hananeelove do Kraljeva tijeska."},{"v":11,"t":"Opet će se stanovati u njemu, i više neće biti prokletstva; Jeruzalem će živjeti u miru."},{"v":12,"t":"A evo kojom će ranom Jahve udariti sve narode koji budu zavojštili na Jeruzalem: meso će im se raspadati dok budu na nogama; oči će im trunuti u dupljama, jezik gnjiti u ustima."},{"v":13,"t":"U dan onaj nastat će među njima silan metež od Jahve: jedan će drugoga za ruku hvatati, i ruka će se jednoga dizati na drugoga."},{"v":14,"t":"I Juda će se boriti u Jeruzalemu. Tu će se sakupiti bogatstva svih okolnih naroda: zlato, srebro, odjeća u velikoj množini."},{"v":15,"t":"A slična će rana pasti na konje, mazge, deve i magarce, i na svu stoku koja se nađe u tome taboru."},{"v":16,"t":"Tko preživi od svih naroda koji dođu na Jeruzalem, uzlazit će godimice da se pokloni pred Kraljem, Jahvom nad Vojskama, i da slave Blagdan sjenica."},{"v":17,"t":"Ako koje pleme zemlje ne uzađe u Jeruzalem da se pokloni pred Kraljem, Jahvom nad Vojskama, neće biti kiše za njega."},{"v":18,"t":"Ako li pleme egipatsko ne uzađe i ne dođe, stići će ga isti udarac kojim će Jahve udariti narode koji ne bi uzašli svetkovati Blagdan sjenica."},{"v":19,"t":"Takva će biti kazna Egiptu i svim narodima koji ne budu uzašli da svetkuju Blagdan sjenica."},{"v":20,"t":"U onaj dan stajat će na konjskim praporcima 'Jahvi posvećen'; a u Domu Jahvinu bit će lonci kao žrtvene čaše pred žrtvenikom;"},{"v":21,"t":"i svaki će lonac u Jeruzalemu i u Judeji biti posvećen Jahvi nad Vojskama - svi koji budu htjeli žrtvovati uzimat će ih i kuhati u njima. I u dan onaj neće više biti trgovaca u Domu Jahve nad Vojskama."}]}},"MAL":{"1":{"hr":[{"v":1,"t":"Proroštvo. Riječ Gospodnja Izraelu po Malahiji."},{"v":2,"t":"Ljubio sam vas - govori Jahve, a vi pitate: “Po čemu si nas ljubio?” Ne bijaše li Ezav brat Jakovljev? - riječ je Jahvina -"},{"v":3,"t":"ali Jakova sam zavolio, a Ezav mi omrznu: gradove mu u pustoš pretvorih, a baštinu njegovu dadoh pustinjskim šakalima."},{"v":4,"t":"Jer, rekne li Edom: Bili smo smrvljeni, ali ćemo opet podići ruševine!” ovako kaže Jahve nad Vojskama: Neka grade oni, a ja ću razgraditi! Zvat će ih zemljom bezbožničkom i narodom na koji se Jahve srdi dovijeka!"},{"v":5,"t":"Vaše će oči vidjeti, i reći ćete: “Velik je Jahve preko granica zemlje izraelske.”"},{"v":6,"t":"Sin časti oca, a sluga gospodara. Ali, ako sam ja otac, gdje je čast moja? Ako sam gospodar, gdje je strah od mene? To govori Jahve nad Vojskama vama, svećenici, koji moje ime prezirete, a pitate: “Čime smo prezreli ime tvoje?”"},{"v":7,"t":"Oskvrnjen kruh na mome prinosite žrtveniku i još pitate: “Čime te oskvrnismo?” Time što kažete “Stol je Jahvin stvar nevažna!”"},{"v":8,"t":"A kada za žrtvu slijepu stoku prinosite, zar to nije zlo? I kad prinosite hromo i bolesno, zar to nije zlo? Donesi takvo što svome namjesniku, hoće li biti zadovoljan i dobro te primiti? - govori Jahve nad Vojskama."},{"v":9,"t":"Sada umilostivite lice Božje da nam se smiluje. To donose ruke vaše, hoće li vas dobro primiti? - govori Jahve nad Vojskama."},{"v":10,"t":"O kada bi tko od vas zatvorio vrata da mi zaludu ne palite ognja na žrtveniku! Niste mi mili - govori Jahve nad Vojskama - i ne primam žrtve iz ruke vaše."},{"v":11,"t":"Jer od istoka do zapada veliko je ime moje među narodima, i na svakom mjestu prinosi se kad i žrtva čista Imenu mojemu, jer veliko je Ime moje među narodima - govori Jahve nad Vojskama."},{"v":12,"t":"Ali vi ga skvrnite kada govorite: “Stol je Gospodnji okaljan i hrana na njemu ni za što nije!”"},{"v":13,"t":"Kažete još: “Gle, šteta truda!” i prezirete ga - govori Jahve nad Vojskama. Kada dovodite stoku otetu, hromu i bolesnu, te je prinosite kao dar žrtveni, zar da to iz vaše ruke milostivo primim? - govori Jahve nad Vojskama."},{"v":14,"t":"Proklet bio varalica koji u stadu ima ovna što mi ga je zavjetovao, a žrtvuje mi ovcu jalovicu. Jer ja sam velik kralj - govori Jahve nad Vojskama - i strašno je Ime moje među narodima."}]},"2":{"hr":[{"v":1,"t":"A sad vas opominjem, svećenici!"},{"v":2,"t":"Ako ne budete poslušali, ako ne budete k srcu uzeli da proslavite Ime moje - govori Jahve nad Vojskama - kletvu ću na vas svaliti i proklet ću vaš blagoslov. I već ga prokleh jer to niste k srcu uzeli."},{"v":3,"t":"I slomit ću vam ruku, bacit ću vam u lice izmetine, izmetine vaših svetkovina, i s njima ću vas splaviti."},{"v":4,"t":"Po tom ćete znati: to je bila moja opomena da ostane Savez moj s Levijem - govori Jahve nad Vojskama."},{"v":5,"t":"A moj Savez s njim, to bijaše život i mir - ja sam mu ih dao: bijaše to strah - i on me se bojao, Imena se moga plašio."},{"v":6,"t":"Zakon istine bijaše u njegovim ustima i pakost mu ne kaljaše usana; u miru i pravičnosti hodio je sa mnom i mnoge je od grijeha odvratio."},{"v":7,"t":"Da, usne svećenikove treba da čuvaju znanje, a iz njegovih usta treba tražiti Zakon: ta on je glasnik Jahve nad Vojskama."},{"v":8,"t":"Ali vi ste s puta zašli, učinili ste da se mnogi o Zakon spotiču, raskinuli ste Savez Levijev - govori Jahve nad Vojskama."},{"v":9,"t":"Zato učinih da vas preziru i ponizuju svi narodi jer se putova mojih vi držali niste, nego ste bili pristrani primjenjujuć Zakon."},{"v":10,"t":"Nemamo li svi jednog Oca? Nije li nas jedan Bog stvorio? Zašto smo onda jedan drugome nevjerni te skvrnimo Savez svojih otaca?"},{"v":11,"t":"Iznevjerio se Juda: učinili su sramotu u Izraelu i Jeruzalemu, jer Juda je oskvrnuo Svetinju, Jahvi dragu, i ženi se kćerju tuđega božanstva."},{"v":12,"t":"Svakog tko tako učini, ma tko bio on, nek iskorijeni Jahve iz šatora Jakovljevih i izmeđ onih koji prinose žrtvu Jahvi nad Vojskama!"},{"v":13,"t":"I ovo još vi činite: zalijevate suzama Jahvin žrtvenik tužeći i ridajući, jer on više neće da se žr tvi prikloni, iz ruke mu vaše ona nije ugodna."},{"v":14,"t":"I vi pitate: “Zašto?” Zato što je Jahve bio svjedok između tebe i žene mladosti tvoje kojoj si nevjeran premda ti drugarica bijaše i žena tvoga saveza."},{"v":15,"t":"Nije li On načinio jedno jedino biće dahom životnim obdareno? A što to jedino biće traži? Božanski naraštaj! Poštuj dakle život svoj i ne budi nevjeran ženi svoje mladosti."},{"v":16,"t":"Jer ja mrzim otpuštanje žena - govori Jahve, Bog Izraelov - i onog koji nevjerom haljine svoje kalja - govori Jahve nad Vojskama! Poštujte dakle život svoj, ne budite nevjerni!"},{"v":17,"t":"Dosađujete Jahvi svojim riječima, a pitate: “U čemu mu dosađujemo?” Time što govorite: “Svi koji zlo čine dobro su viđeni u očima Jahvinim i takvi su mu mili!” ili: “Gdje je Bog pravde?”"}]},"3":{"hr":[{"v":1,"t":"Evo šaljem glasnika da put preda mnom pripravi. I doći će iznenada u Hram svoj Gospod koga vi tražite i anđeo Saveza koga žudite. Evo ga, dolazi već - govori Jahve nad Vojskama."},{"v":2,"t":"Ali tko će podnijeti dan njegova dolaska i tko će opstati kad se on pojavi? Jer on je kao oganj ljevačev i kao lužina bjeliočeva."},{"v":3,"t":"I zasjest će kao onaj što topi srebro i pročišćava. Očistit će sinove Levijeve i pročistit će ih kao zlato i srebro, da prinose Jahvi žrtvu u pravednosti."},{"v":4,"t":"Tad će biti draga Jahvi žrtva Judina i jeruzalemska kao u drevne dane i kao prvih godina."},{"v":5,"t":"Doći ću k vama na sud i bit ću spreman svjedok protiv vračeva i preljubnika, protiv onih koji se lažno kunu, protiv onih koji zakidaju plaću radniku, udovici i siroti, protiv onih koji gaze pravo stranaca i mene se ne boje - govori Jahve nad Vojskama."},{"v":6,"t":"Jer ja, Jahve, ne mijenjam se, a vi se, sinovi Jakovljevi, mijenjate bez prestanka!"},{"v":7,"t":"Od vremena svojih otaca odstupate od mojih uredaba i ne čuvate ih. Vratite se meni, a ja ću se vratiti vama - govori Jahve nad Vojskama. Pitate: “Kako da se vratimo?”"},{"v":8,"t":"Smije li čovjek prikraćivati Boga? A vi mene prikraćujete. I pitate: “U čemu te prikratismo?” U desetini i u prinosu."},{"v":9,"t":"Udareni ste prokletstvom jer me prikraćujete vi, sav narod!"},{"v":10,"t":"Donesite čitavu desetinu u riznicu da u mojoj kući bude hrane. Tada me iskušajte - govori Jahve nad Vojskama - neću li vam otvoriti ustave nebeske i neću li izliti na vas punom mjerom blagoslov,"},{"v":11,"t":"neću li zbog vas zaprijetit skakavcu da vam više ne kvari usjeva i da vam ne bude nerodna loza u polju - govori Jahve nad Vojskama."},{"v":12,"t":"Svi će vas narodi tad držati sretnima, jer ćete biti zemlja blaženstva - govori Jahve nad Vojskama."},{"v":13,"t":"Teške su besjede vaše protiv mene - govori Jahve."},{"v":14,"t":"Vi ipak pitate: “Što smo između sebe govorili protiv tebe?” Govorili ste: “Zaludu je Bogu služiti i kakva je korist što njegove čuvamo propise i žalosni hodimo pred Jahvom nad Vojskama."},{"v":15,"t":"Odsad ćemo sretnim zvati oholice: napreduju oni koji zlo čine, i premda Boga iskušavaju, izvuku se!”"},{"v":16,"t":"Ali kad se razgovaraju oni koji se Boga boje, Jahve pazi, sluša ih, i to se pred njim piše u knjigu spomenicu u korist onih koji se boje Jahve i štuju Ime njegovo."},{"v":17,"t":"Moji će biti, moja stečevina - govori Jahve nad Vojskama. U Dan koji spremam bit ću im milostiv kao što je milostiv otac sinu koji mu služi."},{"v":18,"t":"I tada ćete opet razlikovati pravednika od grešnika, onoga koji služi Bogu od onoga koji mu ne služi."},{"v":19,"t":"Jer evo dan dolazi poput peći užaren; oholi i zlikovci bit će kao strnjika: dan koji se bliži spalit će ih - govori Jahve nad Vojskama - da im neće ostati ni korijena ni grančice."},{"v":20,"t":"A vama koji se Imena moga bojite sunce pravde će ogranuti sa zdravljem u zrakama, i vi ćete izlaziti poskakujući kao telad na pašu."},{"v":21,"t":"I gazit ćete bezbožnike kao prah pod nogama u dan koji spremam” - govori Jahve nad Vojskama."},{"v":22,"t":"“Spomenite se Zakona Mojsija, sluge moga, kome sam na Horebu propisao zakone i uredbe za sav Izrael."},{"v":23,"t":"Evo, poslat ću vam proroka Iliju prije nego dođe Dan Jahvin, dan velik i strašan."},{"v":24,"t":"On će obratiti srce otaca k sinovima, a srce sinova k ocima, da ne dođem i ne udarim prokletstvom zemlju.”"}]}}});
